const quran_dataSet=[["₁ سورة الفاتحة","1","بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ ١","بسم الله الرحمن الرحيم","ރަޙްމާންވަންތަ ރަޙީމްވަންތަ ﷲ ގެ އިސްމުފުޅުން ފަށަމެވެ.\n","{بِسْمِ اللَّهِ} أي: أبتدئ بكل اسم لله تعالى، لأن لفظ {اسم} مفرد مضاف، فيعم جميع الأسماء [الحسنى] . {اللَّهِ} هو المألوه المعبود، المستحق لإفراده بالعبادة، لما اتصف به من صفات الألوهية وهي صفات الكمال. {الرَّحْمَنِ الرَّحِيمِ} اسمان دالان على أنه تعالى ذو الرحمة الواسعة العظيمة التي وسعت كل شيء، وعمت كل حي، وكتبها للمتقين المتبعين لأنبيائه ورسله. فهؤلاء لهم الرحمة المطلقة، ومن عداهم فلهم نصيب منها. واعلم أن من القواعد المتفق عليها بين سلف الأمة وأئمتها، الإيمان بأسماء الله وصفاته، وأحكام الصفات. فيؤمنون مثلا بأنه رحمن رحيم، ذو الرحمة التي اتصف بها، المتعلقة بالمرحوم. فالنعم كلها، أثر من آثار رحمته، وهكذا في سائر الأسماء. يقال في العليم: إنه عليم ذو علم، يعلم [به] كل شيء، قدير، ذو قدرة يقدر على كل شيء.","{بِسْمِ اللَّهِ} އެބަހީ: ﷲ ތަޢާލާއަށް ލިބިގެންވާ ކޮންމެ އިސްމުފުޅަކުން މި އަޅާ ފަށަމެވެ. އެހެނީ ’އިސްމު‘ މި ލަފްޒަކީ މުފްރަދު މުޟާފު (އެހެން ލަފްޒަކަށް ނިސްބަތްވެގެންވާ، އަދި އެކައްޗެއްގެ މައްޗަށް ދޭހަކޮށްދޭ) ލަފްޒެކެވެ. ވީމާ (އަރަބި ބަހުގެ ގަވާއިދުގައި ވާގޮތުން ﷲ ގެ) އެންމެހައި ރިވެތި އިސްމުފުޅުތަކަށް ޝާމިލުވެގެންވެއެވެ. {اللَّهِ} އެއީ އިލާހެއް ކަމުގައި ނެންގެވޭ ފަރާތާއި، އަޅުކަން ކުރެވޭ ފަރާތެވެ. އަޅުކަން ޙައްގުވަނީ ހަމައެކަނި އެ އިލާހަށެވެ. އެއީ އިލާހަށް އެންމެ ފުރިހަމަ ސިފަފުޅުތަކުން ލިބިގެންވާތީއެވެ. {الرَّحْمَنِ الرَّحِيمِ} މި ދެ އިސްމުފުޅުން އަންގައިދެނީ ﷲ އީ ފުޅާވެގެންވާ މަތިވެރި ރަހުމަތުގެ ވެރި އިލާހެއް ކަމަށެވެ. އެންމެހައި ތަކެއްޗަށް އެ އިލާހުގެ ރަހުމަތް ތަނަވަސްވެގެން ވެއެވެ. އަދި ދިރޭ ކޮންމެ އެއްޗަކަށް އެ އިލާހުގެ ރަހުމަތް އާންމުވެގެން ވެއެވެ. އަދި ﷲ ފޮނުއްވެވި ނަބިއްޔުންނާއި ރަސޫލުންނަށް ތަބާވި ތަގުވާވެރިންނަށް ރަހުމަތް ލައްވާނެކަމަށް އެ އިލާހު ކަނޑައެޅުއްވައި ލިޔުއްވިއެވެ. ފަހެ ހުރިހާ ގޮތަކުންވެސް ރަހުމަތް ލިބުން ވަނީ އެބައިމީހުންނަށެވެ. އަދި އެ ނޫން މީހުންނަށް ވަނީ ރަހުމަތުގެ ނަސީބުގެ ބައެކެވެ. އަދި ދަންނާށެވެ. އުންމަތުގެ ސަލަފުންނާއި އިމާމުން އެއްބަސްވެފައިވާ އަސާސީ ގަވާއިދުތަކުގެ ތެރޭގައި، ﷲ ގެ އިސްމުފުޅުތަކާއި ސިފަފުޅުތަކަށް އީމާންވުމާއި، އެ ސިފަފުޅުތަކުގެ ހުކުމްތައް ހިމެނެއެވެ. އެ ގޮތުން މިސާލެއް ދަންނަވާ ނަމަ، އެ ބޭކަލުން އީމާންވީ އެ އިލާހީ ރަޙްމާންވަންތަ ރަޙީމްވަން އިލާހު ކަމަށެވެ. އަދި ﷲ ސިފަ ކުރައްވާފައިވާ ގޮތަށް އެ އިލާހަށް ރަހުމަތް ލިބިވޮޑިގެންވާކަމަށެވެ. އަދި މި ރަހުމަތަކީ، ރަހުމަތް ލެއްވިގެންވާ (މަޚްލޫގުންނާ) ގުޅި (އަސަރު ކުރުވާ) ރަހުމަތެއް ކަމަށެވެ. ފަހެ އެންމެހައި ނިއުމަތްތަކަކީ އެ އިލާހުގެ ރަހުމަތުގެ އަސަރުތަކާއި (ޢަލާމާތްތަކެވެ.) ހަމަ މިފަދައިން، ދެން ހުރި ހުރިހާ އިސްމުފުޅުތަކުގައި ވެސް (ދޭހަވުން) އޮތީ މިހެންނެވެ. (އެ ގޮތުން) ’ޢަލީމް‘ މި އިސްމުފުޅާ ގުޅޭ ގޮތުން ބުނާނީ، ހަމަކަށަވަރުން އެ އިލާހީ މޮޅަށް ދެނެވޮޑިގެންވާ، (ނިމުމެއް ނުވާ) އިލްމުފުޅެއްގެ ވެރި އިލާހު ކަމަށެވެ. އެ އިލްމުފުޅުން އެންމެހައި ތަކެތި އެ އިލާހު ދެނެވޮޑިގެން ވެއެވެ. އަދި (ހަމަ އެ ގޮތަށް) ’ގާދީރު‘ (މި އިސްމުފުޅުން ދޭހަވަނީ) އެ އިލާހީ އެންމެހައި ކަމެއްގެ މައްޗަށް ކުޅަދުންވަތަ އިލާހު ކަމުގައެވެ."],["₁ سورة الفاتحة","2","ٱلۡحَمۡدُ لِلَّهِ رَبِّ ٱلۡعَٰلَمِينَ ٢","الحمد لله رب العالمين","އެންމެހައި ހަމްދު ތައުރީފާއި ސަނާއެއް ހައްގުވަނީ އާލަމްތަކުގެ ވެރި ރައްބު، ﷲ އަށެވެ.\n","{الْحَمْدُ لِلَّهِ} [هو] الثناء على الله بصفات الكمال، وبأفعاله الدائرة بين الفضل والعدل، فله الحمد الكامل، بجميع الوجوه. {رَبِّ الْعَالَمِينَ} الرب، هو المربي جميع العالمين -وهم من سوى الله- بخلقه إياهم، وإعداده لهم الآلات، وإنعامه عليهم بالنعم العظيمة، التي لو فقدوها، لم يمكن لهم البقاء. فما بهم من نعمة، فمنه تعالى. وتربيته تعالى لخلقه نوعان: عامة وخاصة. فالعامة: هي خلقه للمخلوقين، ورزقهم، وهدايتهم لما فيه مصالحهم، التي فيها بقاؤهم في الدنيا. والخاصة: تربيته لأوليائه، فيربيهم بالإيمان، ويوفقهم له، ويكمله لهم، ويدفع عنهم الصوارف، والعوائق الحائلة بينهم وبينه، وحقيقتها: تربية التوفيق لكل خير، والعصمة عن كل شر. ولعل هذا [المعنى] هو السر في كون أكثر أدعية الأنبياء بلفظ الرب. فإن مطالبهم كلها داخلة تحت ربوبيته الخاصة. فدل قوله {رَبِّ الْعَالَمِينَ} على انفراده بالخلق والتدبير، والنعم، وكمال غناه، وتمام فقر العالمين إليه، بكل وجه واعتبار.","{الْحَمْدُ لِلَّهِ} މިއީ ﷲ ގެ އެންމެ ފުރިހަމަ ސިފަފުޅުތަކުން އެ އިލާހަށް ސަނާ ދެންނެވުމެވެ. އަދި ފަޟްލުވަންތަކަމާއި އަދުލުވެރިކަމުގެ މައްޗަށް ބިނާވެފައިވާ އެ އިލާހުގެ ޢަމަލުފުޅުތަކުން ސަނާ ދެންނެވުމެވެ. ފަހެ ހުރިހާ ގޮތަކަށްމެ އެ އިލާހަށް ފުރިހަމަ ހަމްދު ލިބިވޮޑިގެންވެއެވެ. {رَبِّ الْعَالَمِينَ} ރައްބަކީ އެންމެހައި އާލަމްތައް ހައްދަވާ ގެންގުޅުއްވާ ބައްލަވާ އިލާހެވެ. ޢާލަމަކީ ﷲ ފިޔަވައި ދެން ހުރި ކޮންމެ އެއްޗެކެވެ. އެ ގޮތުން ﷲ އާލަމްތައް ޚަލްގު ކުރައްވާ، އެބައިމީހުންނާއި ތަކެއްޗަށް ބޭނުންވާ ހުރިހާ އެއްޗެއް ދެއްވާ، އަދި ބޮޑެތި ނިއުމަތްތައް ދެއްވިއެވެ. އެ ނިއުމަތްތައް އެބައިމީހުންނަށް ގެއްލިޖެނަމަ، ފަހެ އެބައިމީހުންނަކަށް ނޫޅެވުނީހެވެ. އެހެނީ އެބައިމީހުންނަށް ލިބިފައިވާ ކޮންމެ ނިއުމަތެއް އައިސްފައިވަނީ، ހަމަ ﷲ ތަޢާލާގެ ޙަޟްރަތުންނެވެ. އަދި ﷲ ތަޢާލާ، އެ އިލާހުގެ ޚަލްގުތަކުން ގެންގުޅުއްވާ ބައްލަވަނީ ދެ ގޮތަކަށެވެ. އާންމާއި ހާއްސަ ގޮތަކަށެވެ. އެ ގޮތުން އާންމު ގޮތަކީ، ﷲ މަޚްލޫގުން ޚަލްގު ކުރައްވައި، އެބައިމީހުންނަށް ރިޒްގު ދެއްވައި، އަދި ދުނިޔޭގައި އުޅުމަށްޓަކައި އެބައިމީހުންނަށް މަސްލަހަތް ހުރި ކަންކަމަށް މަގު ދެއްކެވުމެވެ. އަދި ހާއްސަ ގޮތަކީ، އެ އިލާހުގެ ވަލީވެރިންނަށް ތަރުބިއްޔަތު ދެއްވުމެވެ. އެ ގޮތުން ﷲ އެބައިމީހުންނަށް ތަރުބިއްޔަތު ދެއްވަނީ އީމާންކަމުގައެވެ. އަދި އެބައިމީހުންނަށް އެ ކަމަށް ތައުފީގު ދެއްވާ، އެބައިމީހުންނަށްޓަކައި އީމާންކަން ފުރިހަމަ ކޮށްދެއްވައެވެ. އަދި އެބައިމީހުންނާއި އީމާންކަމާ ދެމެދު ހުރަސް އަޅާ، ދުރުކުރުވާ ކަންތަކުން އެބައިމީހުން ރައްކާތެރި ކޮށްދެއްވައެވެ. މި (ތަރިބިއްޔަތުގެ) ޙަގީގީ މާނައަކީ، ކޮންމެ ހެޔޮ ކަމަކަށް ތައުފީގު ދެއްވުމާއި، ކޮންމެ ނުބައިކަމަކުން ރައްކާތެރި ކޮށްދެވުމެވެ. އަދި ގިނަ ނަބިއްޔުން ’ރައްބު‘ މި ލަފްޒު އެ ބޭކަލުންގެ ދުޢާތަކުގައި ބޭނުން ކުރެއްވި ސަބަބުގެ ސިއްރަކީ މިއީ ކަމުގައިވުން އެކަށީގެންވެއެވެ. އެހެނީ އެ ނަބިއްޔުން އެދިވަޑައިގަތް އެންމެހައި ކަންތައްތައް ވެސް ވަންނަނީ ﷲ ގެ ހާއްސަ ރުބޫބިއްޔަތުގެ ތެރެއަށެވެ. {رَبِّ الْعَالَمِينَ} ﷲ ގެ މި ވަޙީ ބަސްފުޅުން ދޭހަކޮށްދެނީ، ހުރިހާ ގޮތަކުންވެސް ޚަލްގު ކުރުމާއި، (ކާއިނާތު) ހިންގެވުމާއި، އަދި ނިއުމަތްތައް ދެއްވުން ވަނީ ހަމައެކަނި އެ އިލާހަށް ކަމަށެވެ. އަދި ﷲ ގެ ފުދިވޮޑިގަތުމުގެ ފުރިހަމަކަމާއި، އާލަމްތައް ހުރިހާ ގޮތަކުންވެސް އެ އިލާހަށް ބޭނުން ޖެހިފައިވާކަމެވެ."],["₁ سورة الفاتحة","3","ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ ٣","الرحمن الرحيم","(އެ އިލާހީ) ރަޙްމާންވަންތަ ރަޙީމްވަންތަ އިލާހެވެ.\n","{الرَّحْمَنِ الرَّحِيمِ} اسمان دالان على أنه تعالى ذو الرحمة الواسعة العظيمة التي وسعت كل شيء، وعمت كل حي، وكتبها للمتقين المتبعين لأنبيائه ورسله. فهؤلاء لهم الرحمة المطلقة، ومن عداهم فلهم نصيب منها.","{الرَّحْمَنِ الرَّحِيمِ} މި ދެ އިސްމުފުޅުން އަންގައިދެނީ ﷲ އީ ފުޅާވެގެންވާ މަތިވެރި ރަހުމަތުގެ ވެރި އިލާހެއް ކަމަށެވެ. އެންމެހައި ތަކެއްޗަށް އެ އިލާހުގެ ރަހުމަތް ތަނަވަސްވެގެން ވެއެވެ. އަދި ދިރޭ ކޮންމެ އެއްޗަކަށް އެ އިލާހުގެ ރަހުމަތް އާންމުވެގެން ވެއެވެ. އަދި ﷲ ފޮނުއްވެވި ނަބިއްޔުންނާއި ރަސޫލުންނަށް ތަބާވި ތަގުވާވެރިންނަށް ރަހުމަތް ލައްވާނެކަމަށް އެ އިލާހު ކަނޑައެޅުއްވައި ލިޔުއްވިއެވެ. ފަހެ ހުރިހާ ގޮތަކުންވެސް ރަހުމަތް ލިބުން ވަނީ އެބައިމީހުންނަށެވެ. އަދި އެ ނޫން މީހުންނަށް ވަނީ ރަހުމަތުގެ ނަސީބުގެ ބައެކެވެ."],["₁ سورة الفاتحة","4","مَٰلِكِ يَوۡمِ ٱلدِّينِ ٤","مالك يوم الدين","ނިޔާ ކުރައްވާ (ގިޔާމަތް) ދުވަހުގެ ވެރި އިލާހެވެ.\n","{مَالِكِ يَوْمِ الدِّينِ} المالك: هو من اتصف بصفة الملك التي من آثارها أنه يأمر وينهى، ويثيب ويعاقب، ويتصرف بمماليكه بجميع أنواع التصرفات، وأضاف الملك ليوم الدين، وهو يوم القيامة، يوم يدان الناس فيه بأعمالهم، خيرها وشرها، لأن في ذلك اليوم، يظهر للخلق تمام الظهور، كمال ملكه وعدله وحكمته، وانقطاع أملاك الخلائق. حتى [إنه] يستوي في ذلك اليوم، الملوك والرعايا والعبيد والأحرار. كلهم مذعنون لعظمته، خاضعون لعزته، منتظرون لمجازاته، راجون ثوابه، خائفون من عقابه، فلذلك خصه بالذكر، وإلا فهو المالك ليوم الدين ولغيره من الأيام.","{مَالِكِ يَوْمِ الدِّينِ} މާލިކަކީ، ވެރިކަމުގެ ސިފަ ލިބިގެންވާ ފަރާތެވެ. ވެރިކަމުގެ އަސަރުތަކު ތެރޭގައި، އަމުރު ކުރެއްވުމާއި މަނާ ކުރެއްވުމާއި، ސަވާބު ދެއްވުމާއި އަޒާބު ދެއްވުމާއި، އަދި އެ އިލާހަށް ލިބިވޮޑިގެންވާ އަޅުތަކުންނައިގެން އެދިވޮޑިގެންވާ ހުރިހާ ގޮތަކަށް ކަންތައް ކުރެއްވުން ހިމެނެއެވެ. އަދި މި ވެރިކަން ގުޅުއްވުނީ ހިސާބު ބައްލަވާ ދުވަހަށެވެ. އެއީ ގިޔާމަތް ދުވަހެވެ. އެ ދުވަހުގައި މީސްތަކުން ހެޔޮ ޢަމަލުތަކާއި ނުބައި ޢަމަލުތަކުން ހިސާބު ބެއްލެވޭނެއެވެ. އެހެނީ އެ ދުވަހުގައި، ﷲ ގެ ވެރިކަމުގެ ފުރިހަމަކަމާއި، އެ އިލާހުގެ އަދުލުވެރިކަމާއި ހިކުމަތްވަންތަކަން އެންމެ ފާޅުވެގެންވާ ގޮތުގައި ޚަލްގުތަކުންނަށް ފެންނާނެއެވެ. އަދި ޚަލްގުތަކުންނަށް އެއްވެސް ވެރިކަމެއް ނުވާކަން އެބައިމީހުން ދަންނާނެއެވެ. އެ ގޮތުން އެ ދުވަހުގައި ރަސްރަސްކަލުންނާއި ރައްޔިތުންނާއި، އަޅުތަކުންނާއި މިނިވަނުން ހަމަހަމަވެގެންވާނެއެވެ. އެ އިލާހުގެ މަތިވެރިކަމުގެ ކުރިމަތީގައި އެބައިމީހުން އެންމެން ވާނީ ނިކަމެތިން ކަމުގައެވެ. އަދި އެ އިލާހުގެ އިއްޒަތްވަންތަކަމުގެ ކުރިމަތީގައި އެބައިމީހުން ވާނީ ދެރަ ބައެއް ކަމުގައެވެ. އެ އިލާހުގެ ޖަޒާއަށް އެބައިމީހުން އިންތިޒާރު ކުރާނެއެވެ. އެ އިލާހުގެ ސަވާބަށް އެބައިމީހުން އެދޭނެއެވެ. އެ އިލާހުގެ އަޒާބަށް އެބައިމީހުން ބިރުވެތިވާނެއެވެ. މި ދުވަސް ވަކިން ފާހަގަ ކުރެވިފައިވަނީ މިކަމުގެ ސަބަބުންނެވެ. އެހެނީ ގިޔާމަތް ދުވަހާއި އެ ނޫން ދުވަސްތަކުގެ ވެރިއަކީ ވެސް ހަމަ ﷲ އެވެ."],["₁ سورة الفاتحة","5","إِيَّاكَ نَعۡبُدُ وَإِيَّاكَ نَسۡتَعِينُ ٥","إياك نعبد وإياك نستعين","އަޅަމެން އަޅުކަން ކުރަނީ (ހަމައެކަނި) އިބަ އިލާހަށެވެ. އަދި އަޅަމެން ވާގި އެދެނީ ވެސް (ހަމައެކަނި) އިބަ އިލާހުގެ ހަޒުރަތުންނެވެ.","وقوله {إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ} أي: نخصك وحدك بالعبادة والاستعانة، لأن تقديم المعمول يفيد الحصر، وهو إثبات الحكم للمذكور، ونفيه عما عداه. فكأنه يقول: نعبدك، ولا نعبد غيرك، ونستعين بك، ولا نستعين بغيرك. وقدم العبادة على الاستعانة، من باب تقديم العام على الخاص، واهتماما بتقديم حقه تعالى على حق عبده. و {العبادة} اسم جامع لكل ما يحبه الله ويرضاه من الأعمال، والأقوال الظاهرة والباطنة. و {الاستعانة} هي الاعتماد على الله تعالى في جلب المنافع، ودفع المضار، مع الثقة به في تحصيل ذلك. والقيام بعبادة الله والاستعانة به هو الوسيلة للسعادة الأبدية، والنجاة من جميع الشرور، فلا سبيل إلى النجاة إلا بالقيام بهما. وإنما تكون العبادة عبادة، إذا كانت مأخوذة عن رسول الله صلى الله عليه وسلم مقصودا بها وجه الله. فبهذين الأمرين تكون عبادة، وذكر {الاستعانة} بعد {العبادة} مع دخولها فيها، لاحتياج العبد في جميع عباداته إلى الاستعانة بالله تعالى. فإنه إن لم يعنه الله، لم يحصل له ما يريده من فعل الأوامر، واجتناب النواهي.","{إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ} އެބަހީ: އަޅުކަން ކުރުމާއި ވާގި އެދުމުގައި އަޅަމެން ހާއްސަ ކުރަނީ ހަމައެކަނި އިބަ އިލާހެވެ. އެހެނީ (ޖުމްލައިގައި) ކަން ރައްދުވާ ފަރާތް ކުރިއަށް ގެނައުމުން ދޭހަކޮށްދެނީ އެ ފަރާތަކަށް އެކަނިވާ ހާއްސަ ކަމެކެވެ. (ނޯޓު: ގުރްއާނުން ބޭރުގައި އާންމުކޮށް މީހުން ބުނެ އުޅޭނީ މިފަދައިންނެވެ: نَعْبُدُ إِيَّاكَ وَنَسْتَعِينُ إِيَّاكَ) އެއީ ނަންގަނެވުނު ކަންތައް ސާބިތުކޮށް، އެ ނޫން ފަރާތްތަކަށް އެކަން ނަފީ ކުރުމެވެ. މިފަދައިން ބުނާ ކަހަލައެވެ: އަޅަމެން އިބަ އިލާހަށް އަޅުކަން ކުރަމެވެ. އަދި އިބަ އިލާހު ފިޔަވައި އެހެން ފަރާތަކަށް އަޅުކަމެއް ނުކުރަމެވެ. އަދި އަޅަމެން ވާގި އެދެނީ ވެސް އިބަ އިލާހުގެ ޙަޟްރަތުންނެވެ. އަދި އިބަ އިލާހު ފިޔަވައި އެހެން ފަރާތެއްގެ ކިބައިން ވާގި ނޭދެމެވެ. ވާގި އެދުމުގެ ކުރިން އަޅުކަން ކުރުން ނަންގަނެވިފައި ވެއެވެ. އެއީ ހާއްސަ ކަންކަމުގެ ކުރިން އާންމު ކަންކަން ނަންގަތުމުގެ ގޮތުންނެވެ. އަދި ﷲ ތަޢާލާގެ ޙައްގު، އެ އިލާހުގެ އަޅުތަކުންގެ ޙައްގަށް ވުރެ އިސްވެގެންވާކަމަށް އަހައްމިއްޔަތުކަން ދެއްވުމަށެވެ. އަދި ’ޢިބާދާ‘ (އަޅުކަން) މިއީ ﷲ ލޯބިވެވޮޑިގެންވާ އަދި ރުއްސަވާވޮޑިގެންވާ ކޮންމެ ކަމަކަށް ޝާމިލުވާ ލަފްޒެކެވެ. އެއީ ސިއްރާ ފާޅު ޢަމަލުތަކާއި ބަސްތަކުގެ ތެރެއިންނެވެ. އަދި ’އިސްތިޢާނާ‘ (ވާގި އެދުން) މިއީ ފައިދާ ކުރަނިވި ކަންކަން ހޯދުމަށާއި، ގެއްލުން ކުރަނިވި ކަންކަން ދުރު ކުރުމަށްޓަކައި ﷲ އަށް ބަރޯސާވުމެވެ. އެއީ އެ ކަންކަން ހާސިލު ކުރުމުގައި ﷲ އަށް އިތުބާރު ކުރާ ޙާލުގައެވެ. ﷲ އަށް އަޅުކަން ކުރުން މަތީ ގާއިމުވުމާއި، އެ އިލާހުގެ ޙަޟްރަތުން ވާގި އެދި ހުރުމަކީ، ދާއިމީ އުފާވެރިކަން ހާސިލުކޮށްދޭނެ އަދި ހުރިހާ ނުބައިކަމަކުން ސަލާމަތްކޮށްދޭނެ ވަސީލަތެވެ. މި ދެ ކަންތަކާ ނުލާ ނަޖާވާނެ އެއްވެސް ގޮތެއް ނުވެއެވެ. އަދި އަޅުކަން ކުރުން (ޙަގީގަތުގައި ވެސް) އަޅުކަން ކުރުން ކަމުގައި ވާނެ ހަމައެކަނި ގޮތަކީ، ﷲ ގެ ވަޖްހުފުޅު އަދައިގެން، ރަސޫލު ﷲ ﷺ ގެ ފަރާތްޕުޅުން ނެންގެވޭ ނަމައެވެ. މި ދެ ކަންތައް ހިމެނޭ ނަމަ ފަހެ އެއީ އަޅުކަން ކުރުމެވެ. ވާގި އެދުމަކީ އަޅުކަމުގެ ތެރެއިންވާ ކަމަކަށް ވުމާއެކުގައި ވެސް (ޖުމްލައިގައި) އަޅުކަން ކުރުމުގެ ފަހަތަށް ވާގި އެދުން ނަންނަނެވިފައި ވެއެވެ. އެއީ އަޅާ ކުރާ ހުރިހާ އަޅުކަމެއްގައިމެ ﷲ ތަޢާލާގެ ޙަޟްރަތުން ވާގި އެދުމަށް ބޭނުން ޖެހިފައިވާތީއެވެ. އެހެނީ ހަމަކަށަވަރުން ﷲ އޭނާއަށް އެހީތެރިވެވޮޑި ނުގަންނަވާނަމަ، ފަހެ އަމުރު ވެވިގެންވާ ކަންތައް ކުރުމުގައާއި، ނަހީ ކުރެވިފައިވާ ކަންތަކުން ދުރުވުމުގައި އޭނާ އެދޭ ކަންތަކެއް ހާސިލެއް ނުވާނެއެވެ."],["₁ سورة الفاتحة","6","ٱهۡدِنَا ٱلصِّرَٰطَ ٱلۡمُسۡتَقِيمَ ٦","اهدنا الصراط المستقيم","ސީދާވެގެންވާ ތެދުމަގަށް އަޅަމެންނަށް މަގު ދައްކަވާށިއެވެ.","ثم قال تعالى: {اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ} أي: دلنا وأرشدنا، ووفقنا للصراط المستقيم، وهو الطريق الواضح الموصل إلى الله، وإلى جنته، وهو معرفة الحق والعمل به، فاهدنا إلى الصراط واهدنا في الصراط. فالهداية إلى الصراط: لزوم دين الإسلام، وترك ما سواه من الأديان، والهداية في الصراط، تشمل الهداية لجميع التفاصيل الدينية علما وعملا. فهذا الدعاء من أجمع الأدعية وأنفعها للعبد ولهذا وجب على الإنسان أن يدعو الله به في كل ركعة من صلاته، لضرورته إلى ذلك.","އެއަށްފަހު ﷲ ތަޢާލާ ވަޙީ ކުރެއްވިއެވެ: {اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ}  އެބަހީ: ސީދާވެގެންވާ ތެދުމަގު އަޅަމެންނަށް ދައްކަވާ، އެއަށް އިރުޝާދު ދެއްވާ، ތައުފީގު ދެއްވާށިއެވެ. އެއީ ﷲ އަށާއި އެ އިލާހުގެ ސުވަރުގެއަށް ގެންދާނެ ސާފު ސީދާ މަގެވެ. އެ މަގަކީ ޙައްގު ދެނެގަތުމާއި އެއަށް ޢަމަލު ކުރުމެވެ. ފަހެ ސީދާވެގެންވާ ތެދުމަގަށް ދިޔުމަށް އަޅަމެންނަށް ހިދާޔަތް ދައްކަވާ، އަދި ސީދާވެގެންވާ ތެދުމަގު މަތީގައި ވެސް އަޅަމެންނަށް ހިދާޔަތް ދައްކަވާށިއެވެ. އެ ގޮތުން ސީދާވެގެންވާ ތެދުމަގަށް ދިޔުމަށް (އަޅަމެންނަށް) ހިދާޔަތް ދެއްކެވުމަކީ، އިސްލާމް ދީނާ އެއްގޮތަށް އުޅުން މަތީ ލާޒިމު ވުމާއި، އެ ނޫން ހުރިހާ ދީންތަކެއް ދޫކޮށްލުމެވެ. އަދި ސީދާވެގެންވާ ތެދުމަގު މަތީގައި (އަޅަމެންނަށް) ހިދާޔަތް ދެއްކެވުން ޝާމިލުވަނީ، ދީނުގެ ހުރިހާ ތަފްސީލީ ކަންކަމަށް ޢިލްމާއި ޢަމަލުގައި ހިދާޔަތް ދެއްކެވުމަށެވެ. ފަހެ މި ދުޢާއަކީ އެންމެ ގިނަ ކަންތައް އެކުލެވިގެންވާ، އަދި އަޅާއަށް އެންމެ ބޮޑަށް ފައިދާކޮށްދޭނެ އެއް ދުޢާއެކެވެ. ވީމާ އެ ކަމުގެ ސަބަބުން އިންސާނާގެ މައްޗަށް ވާޖިބުވަނީ ނަމާދުގެ ކޮންމެ ރަކުޢަތެއްގައި ﷲ އަށް މި ދުޢާ ދެންނެވުމަށެވެ. އެއީ އޭނާ އެކަމަށް ބޭނުން ޖެހިފައިވާލެއް ބޮޑުކަމުންނެވެ."],["₁ سورة الفاتحة","7","صِرَٰطَ ٱلَّذِينَ أَنۡعَمۡتَ عَلَيۡهِمۡ غَيۡرِ ٱلۡمَغۡضُوبِ عَلَيۡهِمۡ وَلَا ٱلضَّآلِّينَ ٧","صراط الذين أنعمت عليهم غير المغضوب عليهم ولا الضالين","(އެއީ) އެބައިމީހުންނަށް އިބަ އިލާހު ނިއުމަތް ދެއްވި މީހުންގެ މަގެވެ. އެ ބަޔެއްގެ މައްޗަށް ކޯފާ ލެއްވުނު މީހުންގެ މަގެއް ނޫނެވެ. އަދި މަގުފުރެދިފައިވާ މީހުންގެ މަގެއްވެސް ނޫނެވެ.","وهذا الصراط المستقيم هو: {صِرَاطَ الَّذِينَ أَنْعَمْتَ عَلَيْهِمْ} من النبيين والصديقين والشهداء والصالحين. {غَيْرِ} صراط {الْمَغْضُوبِ عَلَيْهِمْ} الذين عرفوا الحق وتركوه كاليهود ونحوهم. وغير صراط {الضَّالِّينَ} الذين تركوا الحق على جهل وضلال، كالنصارى ونحوهم. فهذه السورة على إيجازها، قد احتوت على ما لم تحتو عليه سورة من سور القرآن، فتضمنت أنواع التوحيد الثلاثة: توحيد الربوبية يؤخذ من قوله: {رَبِّ الْعَالَمِينَ} . وتوحيد الإلهية وهو إفراد الله بالعبادة، يؤخذ من لفظ: {اللَّهِ} ومن قوله: {إِيَّاكَ نَعْبُدُ} وتوحيد الأسماء والصفات، وهو إثبات صفات الكمال لله تعالى، التي أثبتها لنفسه، وأثبتها له رسوله من غير تعطيل ولا تمثيل ولا تشبيه، وقد دل على ذلك لفظ {الْحَمْدُ} كما تقدم. وتضمنت إثبات النبوة في قوله: {اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ} لأن ذلك ممتنع بدون الرسالة. وإثبات الجزاء على الأعمال في قوله: {مَالِكِ يَوْمِ الدِّينِ} وأن الجزاء يكون بالعدل، لأن الدين معناه الجزاء بالعدل. وتضمنت إثبات القدر، وأن العبد فاعل حقيقة، خلافا للقدرية والجبرية. بل تضمنت الرد على جميع أهل البدع [والضلال] في قوله: {اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ} لأنه معرفة الحق والعمل به. وكل مبتدع [وضال] فهو مخالف لذلك. وتضمنت إخلاص الدين لله تعالى، عبادة واستعانة في قوله: {إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ} فالحمد لله رب العالمين.","އަދި މި ސީދާވެގެންވާ ތެދުމަގަކީ {صِرَاطَ الَّذِينَ أَنْعَمْتَ عَلَيْهِمْ} އެބައިމީހުންގެ ތެރެއިން ނަބިއްޔުންނާއި ޞިއްދީގުންނާއި ޝަހީދުންނާއި ޞާލިޙު މީހުން ހިމެނޭ، އެބައިމީހުންނަށް އިބަ އިލާހު ނިއުމަތް ދެއްވި މީހުންގެ މަގެވެ. އެއީ {الْمَغْضُوبِ عَلَيْهِمْ} އެ ބަޔެއްގެ މައްޗަށް ކޯފާ ލެއްވުނު މީހުންގެ މަގެއް ނޫނެވެ. އެ ބަޔަކީ ޔަހޫދީންނާއި އެ ނޫން މީހުން ފަދައިން، ޙައްގު ދެނެގަތުމަށް ފަހު އެ ދޫކުރި މީހުންނެވެ. އަދި އެއީ މަގުފުރެދިފައިވާ މީހުންގެ މަގެއްވެސް ނޫނެވެ. އެއީ ނަޞާރާއިންނާއި އެ ނޫން މީހުން ފަދައިން، ޖާހިލު ކަމާއި މަގުފުރެދުމުގެ ސަބަބުން ޙައްގު ދޫކުރި މީހުންނެވެ. ފަހެ މި ސޫރަތުގެ ކުރުކަމާއެކު ވެސް، ގުރްއާންގެ އެހެން ސޫރަތެއްގައި ޝާމިލު ނުވާ އެތަކެއް ކަމެއް މި ސޫރަތުގައި ޝާމިލުވެގެން ވެއެވެ. އެ ގޮތުން ތައުޙީދުގެ ތިން ބާވަތް މި ސޫރަތުގައި އެކުލެވިގެން ވެއެވެ. {رَبِّ الْعَالَمِينَ} ﷲ ގެ މި ވަޙީ ބަސްފުޅުން  ތައުޙީދުއް ރުބޫބިއްޔާ (ރައްބާނީ އެއްކައުވަންތަކަން) ނެންގެވިގެން ދެއެވެ. ތައުޙީދުލް އުލޫހިއްޔާ (އިލާހީ އެއްކައުވަންތަކަމަކީ) އަޅުކަން ކުރުން ހަމައެކަނި ﷲ އަށް ހާއްސަ ކުރުމެވެ. އެ ކަން ނެންގެވިގެން ދަނީ {اللَّهِ} މި ލަފްޒުންނާއި، {إِيَّاكَ نَعْبُدُ} މި ވަޙީ ބަސްފުޅުންނެވެ. އަދި ތައުހީދުލް އަސްމާއި ވައްޞިފާތު (އިސްމުފުޅުތަކާއި ސިފަފުޅުތަކުގައި އެއްކައުވަންތަކަމަކީ) އެންމެ ފުރިހަމަ ސިފަފުޅުތައް ﷲ ތަޢާލާއަށް ވާކަން ސާބިތު ކުރުމެވެ. އެއީ ﷲ އެ އިލާހުގެ އަމިއްލަ ނަފްސުފުޅަށް ސާބިތު ކުރެއްވި، އަދި ﷲ ގެ ރަސޫލާ އެ އިލާހަށް ސާބިތު ކުރެއްވި ސިފަފުޅުތަކެވެ. އަދި އެއީ އެ ސިފަފުޅުތައް ނަފީ ކުރުމެއް، މިސާލު ޖެހުމެއް އަދި ވައްތަރު ކުރުމަކާ ނުލައެވެ. އަދި ކުރީގައި އައިސްފައިވާ ލަފްޒު {الْحَمْدُ} މިކަމުގެ މައްޗަށް ދޭހަކޮށްދެއެވެ. {اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ} ﷲ ގެ މި ވަޙީ ބަސްފުޅުގައި ނުބުއްވަތު ސާބިތުވެގެން ދެއެވެ. އެހެނީ ރިސާލަތައިގެން (ރަސޫލު ބޭކަލުން) ފޮނުއްވުމާ ނުލާ ހިދާޔަތް ދެއްކެވުމެއް ނުވެއެވެ. {مَالِكِ يَوْمِ الدِّينِ} ﷲ ގެ މި ވަޙީ ބަސްފުޅުގައި ޢަމަލުތަކުގެ މައްޗަށް ޖަޒާ ދެއްވާނެކަން ސާބިތުވެގެން ދެއެވެ. އަދި ޖަޒާދެއްވުން ވާނީ އަދުލުވެރިކަމާއެކުގައެވެ. އެހެނީ (މި ތަނުގައި) ’ދީން‘ (ނިޔާ ކުރެއްވުން) މި ބަހުގެ މާނައަކީ ޖަޒާ ދެއްވުމާއި އަދުލުވެރިވުމެވެ. އަދި ގަޟާގަދަރު ވާކަން ސާބިތުވެގެން ދެއެވެ. އަދި އަޅާ ކަންތައް ކުރަނީ ޙަގީގަތުގައި ވެސް (އިޚްތިޔާރާއެކު) ކަން ސާބިތުވެގެން ދެއެވެ. އެއީ ގަދަރީންނާއި ޖަބަރީން ބުނާ ގޮތާ ޚިލާފަށެވެ. (ގަދަރީން ބުނަނީ އިންސާނާ މިނިވަންވެގެން ގޮސް ކަންތައް ކުރަނީ ﷲ ގެ އިރާދަފުޅާ ނުލާކަމަށެވެ. އަދި ޖަބަރީން ބުނަނީ އިންސާނާއަކަށް އިޚްތިޔާރެއް ނުވާކަމަށާއި، ހުރިހާ ކަމެއް ކުރަނީ މަޖުބޫރުން ކަމަށެވެ.) އަދި ކިއެއްތަ، ބިދުޢައާއި މަގުފުރެދުމުގެ ހުރިހާ އަހުލުވެރިންނަށް {اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ}  މި ވަޙީ ބަސްފުޅުން ރައްދު ލިބެއެވެ. އެހެނީ ސީދާވެގެންވާ ތެދުމަގަކީ ޙައްގު ދެނެގަނެ އެއަށް ޢަމަލު ކުރުން ކަމުގައި ވާތީއެވެ. އަދި ކޮންމެ ބިދުޢަވެރި މަގުފުރެދުންތެރިއަކީ އެއާ ޚިލާފަށް ކަންކުރާ ބަޔެކެވެ. އަދި {إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ} ﷲ ގެ މި ވަޙީ ބަސްފުޅުގައި، އަޅުކަން ކުރުމާއި ވާގި އެދުމުގައި ﷲ ތަޢާލަށް ދީނުގައި އިހްލާސްތެރިވާން ޖެހޭނެކަން ދޭހަކޮށްދެއެވެ. ފަހެ އެންމެހައި ހަމްދު ތަޢުރީފާއި ސަނާއެއް ޙައްގުވަނީ އާލަމްތަކުގެ ވެރި ރައްބު، ﷲ އަށެވެ."],["₂ سورة البقرة","1","بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ\n<br><br>\nالٓمٓ ١","بسم الله الرحمن الرحيم الم","އަލިފް، ލާމް، މީމް.","",""],["₂ سورة البقرة","2","ذَٰلِكَ ٱلۡكِتَٰبُ لَا رَيۡبَۛ فِيهِۛ هُدٗى لِّلۡمُتَّقِينَ ٢","ذلك الكتاب لا ريب فيه هدى للمتقين","މިއީ އެ ފޮތެވެ. އެ ފޮތާމެދު އެއްވެސް ޝައްކެއް ނެތެވެ. (މި ފޮތަކީ) ތަގުވާވެރިންނަށް ހުރި ހިދާޔަތެކެވެ.","",""],["₂ سورة البقرة","3","ٱلَّذِينَ يُؤۡمِنُونَ بِٱلۡغَيۡبِ وَيُقِيمُونَ ٱلصَّلَوٰةَ وَمِمَّا رَزَقۡنَٰهُمۡ يُنفِقُونَ ٣","الذين يؤمنون بالغيب ويقيمون الصلاة ومما رزقناهم ينفقون","އެބައިމީހުންނަކީ ޣައިބަށް އީމާންވާ، އަދި ނަމާދު ގާއިމު ކުރާ، އަދި ތިމަން އިލާހު އެބައިމީހުންނަށް ދެއްވި ތަކެތިން ހޭދަ ކުރާ މީހުންނެވެ.","",""],["₂ سورة البقرة","4","وَٱلَّذِينَ يُؤۡمِنُونَ بِمَآ أُنزِلَ إِلَيۡكَ وَمَآ أُنزِلَ مِن قَبۡلِكَ وَبِٱلۡأٓخِرَةِ هُمۡ يُوقِنُونَ ٤","والذين يؤمنون بما أنزل إليك وما أنزل من قبلك وبالآخرة هم يوقنون","އަދި އެބައިމީހުންނަކީ، އިބަ ނަބިއްޔާއަށް ބާވައިލައްވާފައިވާ ފޮތަށާއި، އިބަ ނަބިއްޔާގެ ކުރިން ބާވައިލައްވާފައިވާ ފޮތްތަކަށް އީމާންވާ މީހުންނެވެ. އަދި އާޚިރަތާއި މެދުގައި (އެ ދުވަސް އަންނާނެކަމަށް) އެބައިމީހުން ޔަގީން ކުރެއެވެ.","",""],["₂ سورة البقرة","5","أُوْلَـٰٓئِكَ عَلَىٰ هُدٗى مِّن رَّبِّهِمۡۖ وَأُوْلَـٰٓئِكَ هُمُ ٱلۡمُفۡلِحُونَ ٥","أولئك على هدى من ربهم وأولئك هم المفلحون","އެބައިމީހުން ވަނީ، އެބައިމީހުންގެ ވެރި ރައްބުގެ ހަޒުރަތުން އައި ހިދާޔަތުގެ މަތީގައެވެ. އަދި ކާމިޔާބުވާނެ މީހުންނަކީ ހަމަ އެބައިމީހުންނެވެ.","",""],["₂ سورة البقرة","6","إِنَّ ٱلَّذِينَ كَفَرُواْ سَوَآءٌ عَلَيۡهِمۡ ءَأَنذَرۡتَهُمۡ أَمۡ لَمۡ تُنذِرۡهُمۡ لَا يُؤۡمِنُونَ ٦","إن الذين كفروا سواء عليهم أأنذرتهم أم لم تنذرهم لا يؤمنون","ހަމަކަށަވަރުން ކާފިރުވި މީހުންނަށް، އިބަ ނަބިއްޔާ އިންޒާރު ދެއްވިޔަސް ނުވަތަ ނުދެއްވިޔަސް ހަމަހަމަވެގެން ވެއެވެ. އެބައިމީހުން އީމާނެއް ނުވާނެއެވެ.","",""],["₂ سورة البقرة","7","خَتَمَ ٱللَّهُ عَلَىٰ قُلُوبِهِمۡ وَعَلَىٰ سَمۡعِهِمۡۖ وَعَلَىٰٓ أَبۡصَٰرِهِمۡ غِشَٰوَةٞۖ وَلَهُمۡ عَذَابٌ عَظِيمٞ ٧","ختم الله على قلوبهم وعلى سمعهم وعلى أبصارهم غشاوة ولهم عذاب عظيم","ﷲ، އެބައިމީހުންގެ ހިތްތަކުގައްޔާއި އެބައިމީހުންގެ ކަންފަތްތަކުގައި ވަނީ ސިއްކަ ޖައްސަވާ ބަންދު ކުރައްވާފައެވެ. އަދި އެބައިމީހުންގެ ލޯތަކުގެ މަތީގައި ވަނީ ފަރުދާއެކެވެ. އަދި އެބައިމީހުންނަށް ބޮޑުވެގެންވާ އަޒާބު ހުއްޓެވެ.","",""],["₂ سورة البقرة","8","وَمِنَ ٱلنَّاسِ مَن يَقُولُ ءَامَنَّا بِٱللَّهِ وَبِٱلۡيَوۡمِ ٱلۡأٓخِرِ وَمَا هُم بِمُؤۡمِنِينَ ٨","ومن الناس من يقول آمنا بالله وباليوم الآخر وما هم بمؤمنين","އަދި ’ﷲ އާއި އާޚިރަތް ދުވަހަށް ތިމަންމެން  އީމާންވެއްޖައިމޭ‘ ބުނާ  ބަޔަކު މީސްތަކުންގެ ތެރޭގައި ވެއެވެ. ނަމަވެސް އެބައިމިހުން (ހަގީގަތުގައި) އީމާނެއް ނުވެއެވެ.","",""],["₂ سورة البقرة","9","يُخَٰدِعُونَ ٱللَّهَ وَٱلَّذِينَ ءَامَنُواْ وَمَا يَخۡدَعُونَ إِلَّآ أَنفُسَهُمۡ وَمَا يَشۡعُرُونَ ٩","يخادعون الله والذين آمنوا وما يخدعون إلا أنفسهم وما يشعرون","(އެބައިމީހުން ހީކުރާ ގޮތުގައި) ﷲ އަށާއި އީމާންވެގެން ތިބި މީހުންނަށް އެބައިމީހުން އޮޅުވައިލަނީއެވެ. ނަމަވެސް އެބައިމީހުން އެ އޮޅުވައިލަނީ ހަމައެކަނި އެބައިމީހުންގެ އަމިއްލަ ނަފުސުތަކަށެވެ. ނަމަވެސް އެބައިމީހުންނަށް އެ ކަން ނޭނގެނީއެވެ.","",""],["₂ سورة البقرة","10","فِي قُلُوبِهِم مَّرَضٞ فَزَادَهُمُ ٱللَّهُ مَرَضٗاۖ وَلَهُمۡ عَذَابٌ أَلِيمُۢ بِمَا كَانُواْ يَكۡذِبُونَ ١٠","في قلوبهم مرض فزادهم الله مرضا ولهم عذاب أليم بما كانوا يكذبون","އެބައިމީހުންގެ ހިތްތަކުގައި ބަލިމަޑުކަމެއް ވެއެވެ. ފަހެ އެބައިމީހުންގެ މައްޗަށް އެ ބަލިމަޑުކަން ﷲ އިތުރު ކުރެއްވިއެވެ. އަދި އެބައިމީހުން ދޮގުހަދައި އުޅުނުކަމަށްޓަކައިއެބައިމީހުންނަށް ވޭންދެނިވި އަޒާބުހުއްޓެވެ.","",""],["₂ سورة البقرة","11","وَإِذَا قِيلَ لَهُمۡ لَا تُفۡسِدُواْ فِي ٱلۡأَرۡضِ قَالُوٓاْ إِنَّمَا نَحۡنُ مُصۡلِحُونَ ١١","وإذا قيل لهم لا تفسدوا في الأرض قالوا إنما نحن مصلحون","އަދި ’ތިޔަބައިމީހުން ބިމުގައި ފަސާދަ އުފައްދައި ނޫޅޭށޭ‘ އެބައިމީހުންނަށް ބުނެފިނަމަ، އެބައިމީހުންނަކީ ހަމައެކަނި އިސްލާހު ކުރާ ބައެއްކަމުގައި އެބައިމީހުން  ބުނެއެވެ.","",""],["₂ سورة البقرة","12","أَلَآ إِنَّهُمۡ هُمُ ٱلۡمُفۡسِدُونَ وَلَٰكِن لَّا يَشۡعُرُونَ ١٢","ألا إنهم هم المفسدون ولكن لا يشعرون","ދަންނާށެވެ. ހަމަކަށަވަރުން އެބައިމީހުންނަކީ، ހަމަ ފަސާދަ ކުރާ މީހުންނެވެ. ނަމަވެސް އެބައިމީހުންނަށް އެ ކަން ނޭނގެނީއެވެ.","",""],["₂ سورة البقرة","13","وَإِذَا قِيلَ لَهُمۡ ءَامِنُواْ كَمَآ ءَامَنَ ٱلنَّاسُ قَالُوٓاْ أَنُؤۡمِنُ كَمَآ ءَامَنَ ٱلسُّفَهَآءُۗ أَلَآ إِنَّهُمۡ هُمُ ٱلسُّفَهَآءُ وَلَٰكِن لَّا يَعۡلَمُونَ ١٣","وإذا قيل لهم آمنوا كما آمن الناس قالوا أنؤمن كما آمن السفهاء ألا إنهم هم السفهاء ولكن لا يعلمون","އަދި ’މީސްތަކުން އީމާންވި ފަދައިން ތިޔަބައިމީހުން އީމާންވާށޭ‘ އެބައިމީހުންނަށް ބުނެފިނަމަ، ’މޮޔައިން އީމާންވި ފަދައިން އަހަރެމެން އީމާންވާންވީހެއްޔޭ‘ އެބައިމީހުން ބުނެއެވެ.  ދަންނާށެވެ. ހަމަކަށަވަރުން މޮޔައިންނަކީ ހަމަ އެބައިމީހުންނެވެ. ނަމަވެސް އެބައިމީހުންނަށް އެ ކަން ނޭނގެނީއެވެ.","",""],["₂ سورة البقرة","14","وَإِذَا لَقُواْ ٱلَّذِينَ ءَامَنُواْ قَالُوٓاْ ءَامَنَّا وَإِذَا خَلَوۡاْ إِلَىٰ شَيَٰطِينِهِمۡ قَالُوٓاْ إِنَّا مَعَكُمۡ إِنَّمَا نَحۡنُ مُسۡتَهۡزِءُونَ ١٤","وإذا لقوا الذين آمنوا قالوا آمنا وإذا خلوا إلى شياطينهم قالوا إنا معكم إنما نحن مستهزئون","އަދި އީމާންވީ މީހުންނާ އެބައިމީހުން ބައްދަލުވެއްޖެ ނަމަ، ’ތިމަންމެން މިތިބީ އީމާންވެގެންނޭ‘ އެބައިމީހުން ބުނެއެވެ. އަދި އެއުރެންގެ ޝައިތާނުންނާ (އެބަހީ: ދެކޮޅުވެރިކަމާއި ކުފުރުވެރިކަމުގައި އެއުރެންގެތެރެއިން ކުރިޔަށް ތިބިމީހުންނާ) އެބައިމީހުން އެއްތަންވެއްޖެ ނަމަ، އެބައިމީހުން ބުނެއުޅެނީ ’ތިމަންމެން ވަނީ ހަމަކަށަވަރުން ތިޔަބައިމީހުންނާ އެކުގައެވެ. ފުރައްސާރަ ކުރާ ބައެއްކަމުގައި މެނުވީ ތިމަންމެން ނުވަމެވެ.‘","",""],["₂ سورة البقرة","15","ٱللَّهُ يَسۡتَهۡزِئُ بِهِمۡ وَيَمُدُّهُمۡ فِي طُغۡيَٰنِهِمۡ يَعۡمَهُونَ ١٥","الله يستهزئ بهم ويمدهم في طغيانهم يعمهون","އެބައިމީހުން ކުރި ފުރައްސާރައިގެ ޖަޒާ ﷲ އެބައިމީހުންނަށް ދެއްވާނެއެވެ. އަދި ދެފުށުއެޅޭ ޙާލުގައި، އެބައިމީހުންގެ އުރެދުމުގައި އުޅުމަށް އެބައިމީހުންނަށް މުއްދަތު ދިގުކުރައްވާނެތެވެ.","",""],["₂ سورة البقرة","16","أُوْلَـٰٓئِكَ ٱلَّذِينَ ٱشۡتَرَوُاْ ٱلضَّلَٰلَةَ بِٱلۡهُدَىٰ فَمَا رَبِحَت تِّجَٰرَتُهُمۡ وَمَا كَانُواْ مُهۡتَدِينَ ١٦","أولئك الذين اشتروا الضلالة بالهدى فما ربحت تجارتهم وما كانوا مهتدين","އެބައިމީހުންނީ، ހިދާޔަތުގެ ބަދަލުގައި މަގުފުރެދުން ގަތް މީސްތަކުންނެވެ ފަހެ، އެބައިމީހުންގެ އެ ވިޔަފާރިއަކުން، އެބައިމީހުންނަކަށް ފައިދާއެއް ނުވިއެވެ. އަދި އެބައިމީހުންނަކީ ތެދުމަގު ލިބިގެންވާ ބަޔެއް ކަމުގައިވެސް ނުވެއެވެ.","",""],["₂ سورة البقرة","17","مَثَلُهُمۡ كَمَثَلِ ٱلَّذِي ٱسۡتَوۡقَدَ نَارٗا فَلَمَّآ أَضَآءَتۡ مَا حَوۡلَهُۥ ذَهَبَ ٱللَّهُ بِنُورِهِمۡ وَتَرَكَهُمۡ فِي ظُلُمَٰتٖ لَّا يُبۡصِرُونَ ١٧","مثلهم كمثل الذي استوقد نارا فلما أضاءت ما حوله ذهب الله بنورهم وتركهم في ظلمات لا يبصرون","އެބަައިމީހުންގެ މިސާލަކީ، އަލިފާންގަނޑެއް ރޯކޮށްގެންތިބި ބަޔެއްގެ މިސާލެވެ. ފަހެ އެ އަލިފާންގަނޑުން، އެބައިމީހުންގެ ވަށައިިގެންވާ ތަނަށް އަލިކޮށްލި ހިނދު، ﷲ އެބައިމީހުންގެ (އެ އަލިފާންގަނޑުގެ) އަލިިކަން ގެންދަވައި އެބައިމީހުންނަށް އެއްޗެއް ނުފެންނަފަދަ އަނދިރިގަނޑުތަކެއްގެ ތެރެއަށް އެބައިމީހުން ދޫކުރެއްވީއެވެ.","",""],["₂ سورة البقرة","18","صُمُّۢ بُكۡمٌ عُمۡيٞ فَهُمۡ لَا يَرۡجِعُونَ ١٨","صم بكم عمي فهم لا يرجعون","(އެބައިމީހުންނީ) ބީރު، މަންމަން، ކަނު ބަޔެކެވެ. ފަހެ އެބައިމީހުން (ހައްގުގެ މަގަކަށް) ރުޖޫއައެއް ނުވާނެއެވެ.","",""],["₂ سورة البقرة","19","أَوۡ كَصَيِّبٖ مِّنَ ٱلسَّمَآءِ فِيهِ ظُلُمَٰتٞ وَرَعۡدٞ وَبَرۡقٞ يَجۡعَلُونَ أَصَٰبِعَهُمۡ فِيٓ ءَاذَانِهِم مِّنَ ٱلصَّوَٰعِقِ حَذَرَ ٱلۡمَوۡتِۚ وَٱللَّهُ مُحِيطُۢ بِٱلۡكَٰفِرِينَ ١٩","أو كصيب من السماء فيه ظلمات ورعد وبرق يجعلون أصابعهم في آذانهم من الصواعق حذر الموت والله محيط بالكافرين","ނުވަތަ އެބައިމީހުންގެ މިސާލަކީ، އެ ވިލާގަނޑެއްގައި އަނދިރިތަކަމާއި ގުގުރުމާއި ވިދުން (އެކުލެވިފައި) ވާގޮތުގައި އުޑުމަތީގައިވާ ވާރޭވިލާގަނޑެއްގެ މިސާލެވެ. ހޮނުގެ ސަބަބުން މަރުވެދާނެކަމަށް ބިރުން، އެބައިމީހުންގެ ކަންފަތްތަކުގައި އިނގިލިތައް އަޅައެވެ. އަދި ﷲ އީ، ކާފިރުންގެ ހުރިހާ ކަމެއް ފުރިހަމައަށް ދެނެވޮޑިގެންވާ އިލާހެވެ.","",""],["₂ سورة البقرة","20","يَكَادُ ٱلۡبَرۡقُ يَخۡطَفُ أَبۡصَٰرَهُمۡۖ كُلَّمَآ أَضَآءَ لَهُم مَّشَوۡاْ فِيهِ وَإِذَآ أَظۡلَمَ عَلَيۡهِمۡ قَامُواْۚ وَلَوۡ شَآءَ ٱللَّهُ لَذَهَبَ بِسَمۡعِهِمۡ وَأَبۡصَٰرِهِمۡۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٞ ٢٠","يكاد البرق يخطف أبصارهم كلما أضاء لهم مشوا فيه وإذا أظلم عليهم قاموا ولو شاء الله لذهب بسمعهم وأبصارهم إن الله على كل شيء قدير","އެ ވިދުން، އެބައިމީހުންގެ ލޯތަކުގެ ފެނުން ޖަހައިގަނެގެން އަތުލާފާނެ ކަހަލައެވެ. އެ ވިދުން އެބައިމީހުންނަށް އަލިކޮށްލި ކޮންމެހިނދަކު އެ އަލީގައި އެބައިމީހުން ހިނގައިގަނެއެވެ. އަދި އެބައިމީހުންނަށް އަނދިރި އަޅާލައިފިނަމަ، ހުއްޓުން އަރާފައި ތިބެއެވެ. ﷲ އިރާދަކުރައްވައިފި ނަމަ، އެބައިމީހުންގެ ކަންފަތްތަކުގެ އިވުމާއި، ލޯތަކުގެ ފެނުން ގެންދަވައިފީހެވެ. ހަމަކަށަވަރުން ﷲ އީ، ކޮންމެކަމަކަށް ވެސް ކުޅަދުންވަންތަ އިލާހެވެ.","",""],["₂ سورة البقرة","21","يَـٰٓأَيُّهَا ٱلنَّاسُ ٱعۡبُدُواْ رَبَّكُمُ ٱلَّذِي خَلَقَكُمۡ وَٱلَّذِينَ مِن قَبۡلِكُمۡ لَعَلَّكُمۡ تَتَّقُونَ ٢١","يا أيها الناس اعبدوا ربكم الذي خلقكم والذين من قبلكم لعلكم تتقون","އޭ މީސްތަކުންނެވެ. ތިޔަބައިމީހުންގެ ވެރި ރައްބަށް އަޅުކަން ކުރާށެވެ. އެ އިލާހީ، ތިޔަބައިމީހުންނާއި ތިޔަބައިމީހުންގެ ކުރިން އުޅުނު މީހުން ހެއްދެވި ރައްބެވެ. (އަޅުކަން ކުރަންވީ) ތިޔަބައިމީހުން ތަގުވާވެރި ވުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","22","ٱلَّذِي جَعَلَ لَكُمُ ٱلۡأَرۡضَ فِرَٰشٗا وَٱلسَّمَآءَ بِنَآءٗ وَأَنزَلَ مِنَ ٱلسَّمَآءِ مَآءٗ فَأَخۡرَجَ بِهِۦ مِنَ ٱلثَّمَرَٰتِ رِزۡقٗا لَّكُمۡۖ فَلَا تَجۡعَلُواْ لِلَّهِ أَندَادٗا وَأَنتُمۡ تَعۡلَمُونَ ٢٢","الذي جعل لكم الأرض فراشا والسماء بناء وأنزل من السماء ماء فأخرج به من الثمرات رزقا لكم فلا تجعلوا لله أندادا وأنتم تعلمون","އެ އިލާހީ، ތިޔަބައިމީހުންނަށް ޓަކައި ތަންމައްޗެއް ކަމުގައި ބިން ލައްވައި، އަދި ބިނާއެއް ކަމުގައި އުޑު ލައްވައި، އުޑުން ފެން ވެއްސަވައި، އެއިން ތިޔަބައިމީހުންނަށް ރިޒްގެއް ކަމުގައި މޭވާގެ ބާވަތްތައް ނެރުއްވި އިލާހެވެ. ފަހެ (އެ އިލާހުގެ ޚާލިގުވަންތަކަން) ތިޔަބައިމީހުން ދެނެތިބެ، ﷲ އަށް ޝަރީކުންތަކެއް ތިޔަބައިމީހުން ނުލާށެވެ.","",""],["₂ سورة البقرة","23","وَإِن كُنتُمۡ فِي رَيۡبٖ مِّمَّا نَزَّلۡنَا عَلَىٰ عَبۡدِنَا فَأۡتُواْ بِسُورَةٖ مِّن مِّثۡلِهِۦ وَٱدۡعُواْ شُهَدَآءَكُم مِّن دُونِ ٱللَّهِ إِن كُنتُمۡ صَٰدِقِينَ ٢٣","وإن كنتم في ريب مما نزلنا على عبدنا فأتوا بسورة من مثله وادعوا شهداءكم من دون الله إن كنتم صادقين","ތިމަންރަސްކަލާނގެ އަޅާއަށް (އެބަހީ: މުޙައްމަދުގެފާނަށް) ތިމަންރަސްކަލާނގެ ބާވައިލެއްވި އެއްޗަކާމެދު (އެބަހީ: ގުރްއާނާމެދު) ތިޔަބައިމީހުން ޝައްކުކަމެއްގައި ވަނީނަމަ، ފަހެ ތިޔަބައިމީހުން އޭގައިވާފަދަ ސޫރަތެއް ނިކަން ގެނެސްބަލާށެވެ! އަދި ތިޔަބައިމީހުން ތެދުވެރިން ކަމުގައި ވަނީނަމަ، ﷲ ފިޔަވައި ތިޔަބައިމީހުންނަށް ނަސްރު ދޭނޭ އެހީތެރިން (ތިބިނަމަ، އެއުރެން) ނަށް ނިކަން ގޮވައި، ގެނެސްބަލާށެވެ!","",""],["₂ سورة البقرة","24","فَإِن لَّمۡ تَفۡعَلُواْ وَلَن تَفۡعَلُواْ فَٱتَّقُواْ ٱلنَّارَ ٱلَّتِي وَقُودُهَا ٱلنَّاسُ وَٱلۡحِجَارَةُۖ أُعِدَّتۡ لِلۡكَٰفِرِينَ ٢٤","فإن لم تفعلوا ولن تفعلوا فاتقوا النار التي وقودها الناس والحجارة أعدت للكافرين","ފަހެ، ތިޔަބައިމީހުންނަށް އެކަން ނުކުރެވުނުނަމަ - އަދި ތިޔަބައިމީހުންނަކަށް ހަމަ ހިލާ އެކަންތަކެއް ނުމެ ކުރެވޭނެއެވެ. - (އެކަން ނުކުރެވުނުނަމަ) ފަހެ، ތިޔަބައިމީހުން ނަރަކަޔަށް ބިރުވެތިވެ، ރައްކާތެރިވާށެވެ! އެނަރަކަޔަކީ، މީހުންނާއި ހިލަ، އޭގެ ދަރުކަމުގައިވާ ނަރަކައެވެ. އެ ނަރަކަ ތައްޔާރު ކުރައްވާފައިވަނީ، ކާފިރުންނަށްޓަކައެވެ.","",""],["₂ سورة البقرة","25","وَبَشِّرِ ٱلَّذِينَ ءَامَنُواْ وَعَمِلُواْ ٱلصَّـٰلِحَٰتِ أَنَّ لَهُمۡ جَنَّـٰتٖ تَجۡرِي مِن تَحۡتِهَا ٱلۡأَنۡهَٰرُۖ كُلَّمَا رُزِقُواْ مِنۡهَا مِن ثَمَرَةٖ رِّزۡقٗا قَالُواْ هَٰذَا ٱلَّذِي رُزِقۡنَا مِن قَبۡلُۖ وَأُتُواْ بِهِۦ مُتَشَٰبِهٗاۖ وَلَهُمۡ فِيهَآ أَزۡوَٰجٞ مُّطَهَّرَةٞۖ وَهُمۡ فِيهَا خَٰلِدُونَ ٢٥","وبشر الذين آمنوا وعملوا الصالحات أن لهم جنات تجري من تحتها الأنهار كلما رزقوا منها من ثمرة رزقا قالوا هذا الذي رزقنا من قبل وأتوا به متشابها ولهم فيها أزواج مطهرة وهم فيها خالدون","އަދި އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަ މީހުންނަށްޓަކައި، ހަމަކަށަވަރުން ސުވަރުގެތަކެއް ހުރިކަމުގެ އުފާވެރި ޚަބަރު ކަލޭގެފާނު އެއުރެންނަށް ދެއްވާށެވެ! އެ ސުވަރުގެތަކުގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގައި ހުރެތެވެ. އެ ސުވަރުގެތަކުން ރޯއްޖެއްގެ ގޮތުގައި މޭވާގެ ކޮންމެވެސް ބާވަތެއް، އެއުރެންނަށް ލިބޭ ކޮންމެ ފަހަރަކު، އެއުރެން ބުނާނެތެވެ. މިއީ ކުރިންވެސް އަހަރެމެންނަށް ލިބުނު މޭވާއެވެ. އެއުރެންނަށް އެފަދަ މޭވާ ދެއްވާހުށީ (ބޭރުފުށުން) އެއްވައްތަރުވާ ޙާލު ގައެވެ. އަދި އެ ސުވަރުގެ ތަކުގައި އެއުރެންނަށްޓަކައި ތާހިރު ވެގެންވާ އަނބިން ފިރިންތަކެއް ވެއެވެ. އަދި އެއުރެންނީ، އެ ސުވަރުގެތަކުގައި ދެމިތިބޭނޭ ބަޔެކެވެ.","",""],["₂ سورة البقرة","26","۞إِنَّ ٱللَّهَ لَا يَسۡتَحۡيِۦٓ أَن يَضۡرِبَ مَثَلٗا مَّا بَعُوضَةٗ فَمَا فَوۡقَهَاۚ فَأَمَّا ٱلَّذِينَ ءَامَنُواْ فَيَعۡلَمُونَ أَنَّهُ ٱلۡحَقُّ مِن رَّبِّهِمۡۖ وَأَمَّا ٱلَّذِينَ كَفَرُواْ فَيَقُولُونَ مَاذَآ أَرَادَ ٱللَّهُ بِهَٰذَا مَثَلٗاۘ يُضِلُّ بِهِۦ كَثِيرٗا وَيَهۡدِي بِهِۦ كَثِيرٗاۚ وَمَا يُضِلُّ بِهِۦٓ إِلَّا ٱلۡفَٰسِقِينَ ٢٦","إن الله لا يستحيي أن يضرب مثلا ما بعوضة فما فوقها فأما الذين آمنوا فيعلمون أنه الحق من ربهم وأما الذين كفروا فيقولون ماذا أراد الله بهذا مثلا يضل به كثيرا ويهدي به كثيرا وما يضل به إلا الفاسقين","ހަމަކަށަވަރުން މަދިރިއަކުން، ނުވަތަ އެއަށްވުރެ ބޮޑު އެއްޗަކުންވިޔަސް، އެއްވެސް ކަހަލަ މިސާލެއް ޖެއްސެވުމަކަށް ﷲ ލަދުވެތިވެވޮޑިގެނެއް ނުވެތެވެ. ފަހެ، އީމާންވި މީހުން، އެ މިސާލަކީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ހައްގު ގޮތުގައި ޖެއްސެވި މިސާލެއްކަން ހަމަކަށަވަރުން ދަނެތެވެ. އަދި ކާފިރުވި މީހުން ބުނެތެވެ. ތިޔަ މިސާލުން، ﷲ އިރާދަކުރެއްވީ ކޮންކަމެއް ބާވައެވެ؟ އެ މިސާލުން، އެކަލާނގެ ގިނަބަޔަކު މަގުފުރައްދަވަތެވެ. އަދި ހަމަ އެ މިސާލުން، އެކަލާނގެ ގިނަބަޔަކަށް ތެދުމަގު ދައްކަވަތެވެ. ފާސިގުން މެނުވީ، އެއިން އެކަލާނގެ މަގެއް ނުފުރައްދަވަތެވެ.","",""],["₂ سورة البقرة","27","ٱلَّذِينَ يَنقُضُونَ عَهۡدَ ٱللَّهِ مِنۢ بَعۡدِ مِيثَٰقِهِۦ وَيَقۡطَعُونَ مَآ أَمَرَ ٱللَّهُ بِهِۦٓ أَن يُوصَلَ وَيُفۡسِدُونَ فِي ٱلۡأَرۡضِۚ أُوْلَـٰٓئِكَ هُمُ ٱلۡخَٰسِرُونَ ٢٧","الذين ينقضون عهد الله من بعد ميثاقه ويقطعون ما أمر الله به أن يوصل ويفسدون في الأرض أولئك هم الخاسرون","އެއުރެންނީ، ﷲއަށް އަހުދު ކަށަވަރުކޮށް ގަދަކުރުމަށްފަހު އެކަލާނގެ އަހުދު އުވައިލާ މީހުންނެވެ. އަދި އެއުރެންނީ، ގުޅުވައި ދެމެހެއްޓުމަށް ﷲ އަމުރުކުރެއްވި ކަންތައްތައް ކަނޑާލައި، ބިމުގައި ފަސާދަ އުފައްދާ މީހުންނެވެ. ގެއްލެނިވެގެންވާ މީހުންނީ، ހަމަ އެއުރެންނެވެ.","",""],["₂ سورة البقرة","28","كَيۡفَ تَكۡفُرُونَ بِٱللَّهِ وَكُنتُمۡ أَمۡوَٰتٗا فَأَحۡيَٰكُمۡۖ ثُمَّ يُمِيتُكُمۡ ثُمَّ يُحۡيِيكُمۡ ثُمَّ إِلَيۡهِ تُرۡجَعُونَ ٢٨","كيف تكفرون بالله وكنتم أمواتا فأحياكم ثم يميتكم ثم يحييكم ثم إليه ترجعون","ތިޔަބައިމީހުން ﷲއަށް ކާފިރު ވެގަންނަނީ، ކޮންގޮތަކުންހެއްޔެވެ؟ ތިޔަބައިމީހުން މަރުވެފައިވާ ބަޔެއްގެ ގޮތުގައި ތިއްބައި، ފަހެ އެކަލާނގެ ތިޔަބައިމީހުން (އުފައްދަވައި) ދިރުއްވިއެވެ. އެއަށްފަހު، އެކަލާނގެ ތިޔަބައިމީހުންގެ (އަޖަލު ހަމަވުމުން) މަރުގަންނަވާނެތެވެ. ދެން (ގިޔާމަތް ދުވަހުން) ތިޔަބައިމީހުން ދިރުއްވާނެތެވެ. ދެން އެކަލާނގެ ހަޒުރަތަށް ތިޔަބައިމީހުން ރުޖޫއަކުރައްވާނެތެވެ.","",""],["₂ سورة البقرة","29","هُوَ ٱلَّذِي خَلَقَ لَكُم مَّا فِي ٱلۡأَرۡضِ جَمِيعٗا ثُمَّ ٱسۡتَوَىٰٓ إِلَى ٱلسَّمَآءِ فَسَوَّىٰهُنَّ سَبۡعَ سَمَٰوَٰتٖۚ وَهُوَ بِكُلِّ شَيۡءٍ عَلِيمٞ ٢٩","هو الذي خلق لكم ما في الأرض جميعا ثم استوى إلى السماء فسواهن سبع سماوات وهو بكل شيء عليم","އެކަލާނގެއީ، ތިޔަބައިމީހުންނަށްޓަކައި ބިމުގައިވާ އެންމެހައި ތަކެތި ހެއްދެވި ރަސްކަލާނގެއެވެ. ދެން އެކަލާނގެ އުޑު ހެއްދެވުމަށް އިރާދަކުރައްވައި، އެ އުޑުތަކުގެ ހެއްދެވުން ހަތް އުޑަށް ފުރިހަމަކުރެއްވިއެވެ. އަދި އެކަލާނގެއީ، ކޮންމެކަމެއްމެ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","30","وَإِذۡ قَالَ رَبُّكَ لِلۡمَلَـٰٓئِكَةِ إِنِّي جَاعِلٞ فِي ٱلۡأَرۡضِ خَلِيفَةٗۖ قَالُوٓاْ أَتَجۡعَلُ فِيهَا مَن يُفۡسِدُ فِيهَا وَيَسۡفِكُ ٱلدِّمَآءَ وَنَحۡنُ نُسَبِّحُ بِحَمۡدِكَ وَنُقَدِّسُ لَكَۖ قَالَ إِنِّيٓ أَعۡلَمُ مَا لَا تَعۡلَمُونَ ٣٠","وإذ قال ربك للملائكة إني جاعل في الأرض خليفة قالوا أتجعل فيها من يفسد فيها ويسفك الدماء ونحن نسبح بحمدك ونقدس لك قال إني أعلم ما لا تعلمون","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ބިމުގައި ޚަލީފާއަކު ލައްވާހުށީމޭ މަލާއިކަތުންނަށް ވަހީކުރެއްވިހިނދު ހަނދުމަކުރައްވާށެވެ! އެބޭކަލުން (އެހިނދު) ދެންނެވޫއެވެ. އަޅަމެން އިބަރަސްކަލާނގެއަށް ހަމްދާއެކު ތަސްބީހަ ކިޔައި، އިބަރަސްކަލާނގެއަށް ތަގުދީސް ކޮށްކޮށް ތިއްބައި، އެ ބިމުގައި ފަސާދަ އުފައްދައި ލޭއޮހޮރުވާނޭ ބަޔަކު އިބަރަސްކަލާނގެ އެ ބިމުގައި ލައްވަނީތޯއެވެ؟ އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށް އެނގިގެންނުވާ ކަންތައްތައް ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގެންވަމެވެ.","",""],["₂ سورة البقرة","31","وَعَلَّمَ ءَادَمَ ٱلۡأَسۡمَآءَ كُلَّهَا ثُمَّ عَرَضَهُمۡ عَلَى ٱلۡمَلَـٰٓئِكَةِ فَقَالَ أَنۢبِـُٔونِي بِأَسۡمَآءِ هَـٰٓؤُلَآءِ إِن كُنتُمۡ صَٰدِقِينَ ٣١","وعلم آدم الأسماء كلها ثم عرضهم على الملائكة فقال أنبئوني بأسماء هؤلاء إن كنتم صادقين","އަދި އާދަމުގެފާނަށް ހުރިހައި ތަކެތީގެ ނަންތައް އެކަލާނގެ އުނގަންނަވައި ދެއްވިއެވެ. (އެބަހީ: ނަންކިޔުނު ތަކެއްޗާއި އެތަކެތީގެ ހަގީގަތް ތަކެވެ.) ދެން، އެކަލާނގެ އެތަކެތި މަލާއިކަތުންނަށް ހުށަހަޅުއްވައި، ވަހީކުރެއްވިއެވެ. ތިޔަބައިމީހުން (ތިޔަކުރާ ދައުވާގައި) ތެދުވެރިންކަމުގައިވަނީނަމަ، މިތަކެތީގެ ނަންތަކުން، ތިޔަބައިމީހުން ތިމަންރަސްކަލާނގެއަށް ނިކަން ޚަބަރު ދީބަލާށެވެ!","",""],["₂ سورة البقرة","32","قَالُواْ سُبۡحَٰنَكَ لَا عِلۡمَ لَنَآ إِلَّا مَا عَلَّمۡتَنَآۖ إِنَّكَ أَنتَ ٱلۡعَلِيمُ ٱلۡحَكِيمُ ٣٢","قالوا سبحانك لا علم لنا إلا ما علمتنا إنك أنت العليم الحكيم","އެ މަލާއިކަތުން ދެންނެވޫއެވެ. އިބަރަސްކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! އިބަރަސްކަލާނގެ އަޅަމެންނަށް އުނގަންނަވައިދެއްވި އެއްޗެއް މެނުވީ، އަޅަމެންނަކަށް އެނގުމެއް ނުވެއެވެ. ހަމަކަށަވަރުން އިބަރަސްކަލާނގެއީ، މޮޅަށް ދެނެވޮޑިގެންވާ ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","33","قَالَ يَـٰٓـَٔادَمُ أَنۢبِئۡهُم بِأَسۡمَآئِهِمۡۖ فَلَمَّآ أَنۢبَأَهُم بِأَسۡمَآئِهِمۡ قَالَ أَلَمۡ أَقُل لَّكُمۡ إِنِّيٓ أَعۡلَمُ غَيۡبَ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ وَأَعۡلَمُ مَا تُبۡدُونَ وَمَا كُنتُمۡ تَكۡتُمُونَ ٣٣","قال يا آدم أنبئهم بأسمائهم فلما أنبأهم بأسمائهم قال ألم أقل لكم إني أعلم غيب السماوات والأرض وأعلم ما تبدون وما كنتم تكتمون","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. އޭ އާދަމުގެފާނެވެ! ކަލޭގެފާނު، އެ މަލާއިކަތުންނަށް އެތަކެތީގެ ނަންތަކުން ޚަބަރު ދެއްވާށެވެ! ދެން އެކަލޭގެފާނު، އެ މަލާއިކަތުންނަށް އެތަކެތީގެ ނަންތަކުން ޚަބަރު ދެއްވިހިނދު، އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އުޑުތަކާއި ބިމުގެ ޣައިބު ދެނެވޮޑިގެންވަމޭ، އަދި ތިޔަބައިމީހުން ފާޅުކުރާ ކަންތަކާއި ވަންހަނާކުރާ ކަންތައް ދެނެވޮޑިގެންވަމޭ، ތިޔަބައިމީހުންނަށް ވަހީ ނުކުރައްވަން ހެއްޔެވެ؟","",""],["₂ سورة البقرة","34","وَإِذۡ قُلۡنَا لِلۡمَلَـٰٓئِكَةِ ٱسۡجُدُواْ لِأٓدَمَ فَسَجَدُوٓاْ إِلَّآ إِبۡلِيسَ أَبَىٰ وَٱسۡتَكۡبَرَ وَكَانَ مِنَ ٱلۡكَٰفِرِينَ ٣٤","وإذ قلنا للملائكة اسجدوا لآدم فسجدوا إلا إبليس أبى واستكبر وكان من الكافرين","އަދި އާދަމުގެފާނަށް ތިޔަބައިމީހުން ސަޖިދަކުރާށޭ ތިމަންރަސްކަލާނގެ މަލާއިކަތުންނަށް ވަހީކުރެއްވިހިނދު، ހަނދުމަކުރައްވާށެވެ! ފަހެ، އިބްލީސް ފިޔަވައި، އެ މަލާއިކަތުން ސަޖިދަކުރެއްވޫއެވެ. އެކަލޭގެ އެކަމުން މަނާވެގަނެ، ކިބުރުވެރިވީއެވެ. އަދި ކާފިރުންގެ ތެރެއިން އެކަލޭގެވިއެވެ.","",""],["₂ سورة البقرة","35","وَقُلۡنَا يَـٰٓـَٔادَمُ ٱسۡكُنۡ أَنتَ وَزَوۡجُكَ ٱلۡجَنَّةَ وَكُلَا مِنۡهَا رَغَدًا حَيۡثُ شِئۡتُمَا وَلَا تَقۡرَبَا هَٰذِهِ ٱلشَّجَرَةَ فَتَكُونَا مِنَ ٱلظَّـٰلِمِينَ ٣٥","وقلنا يا آدم اسكن أنت وزوجك الجنة وكلا منها رغدا حيث شئتما ولا تقربا هذه الشجرة فتكونا من الظالمين","އަދި ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވީމެވެ. އޭ އާދަމުގެފާނެވެ! ކަލޭގެފާނާއި ކަލޭގެފާނުގެ އަނބިކަނބަލުން ސުވަރުގޭގައި ވަޒަންވެރިވެ، އުޅުއްވާށެވެ! އަދި ތަނަވަސްކަމާއި ފަހިކަމާއެކު، ތިޔަ ދެކަނބަލުން އެދިވަޑައިގަންނަވާ ގޮތަކަށް އެތަނުން ފަރިއްކުޅުއްވާށެވެ! އަދި ތިޔަ ދެކަނބަލުން މިހިރަ ގަހާ ކައިރިވެވަޑައި ނުގަންނަވާށެވެ! އޭރުން (އެބަހީ: އެގަހާ ކައިރިވެވަޑައިގެންފިނަމަ) ތިޔަ ދެކަނބަލުންވާހުށީ، އަނިޔާވެރިވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["₂ سورة البقرة","36","فَأَزَلَّهُمَا ٱلشَّيۡطَٰنُ عَنۡهَا فَأَخۡرَجَهُمَا مِمَّا كَانَا فِيهِۖ وَقُلۡنَا ٱهۡبِطُواْ بَعۡضُكُمۡ لِبَعۡضٍ عَدُوّٞۖ وَلَكُمۡ فِي ٱلۡأَرۡضِ مُسۡتَقَرّٞ وَمَتَٰعٌ إِلَىٰ حِينٖ ٣٦","فأزلهما الشيطان عنها فأخرجهما مما كانا فيه وقلنا اهبطوا بعضكم لبعض عدو ولكم في الأرض مستقر ومتاع إلى حين","ފަހެ، ޝައިތާނާ އެ ގަސް މެދުވެރިކޮށް، އެ ދެކަނބަލުން ކުށުގައި އަޅުވައި، ސުވަރުގޭގައި އެ ދެކަނބަލުން އުޅުއްވި ނިއުމަތް ތަކުން އެ ދެކަނބަލުން ބޭރުކޮށްފިއެވެ. އަދި ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވީމެވެ. ތިޔަބައިމީހުންގެ އެއްބަޔަކު އަނެއްބަޔަކާ އަދާވަތް ތެރިން ކަމުގައިވާ ޙާލު، ތިޔަބައިމީހުން (ބިމަށް) ފައިބާށެވެ! އަދި ބިމުގައި ތިޔަބައިމީހުންނަށްޓަކައި، ގަރާރުވެ ތިބެނިވި ތަނަކާއި، ހިނދުކޮޅަކަށް ދުނިޔޭގެ ވަގުތީ އުފަލެއްވެއެވެ.","",""],["₂ سورة البقرة","37","فَتَلَقَّىٰٓ ءَادَمُ مِن رَّبِّهِۦ كَلِمَٰتٖ فَتَابَ عَلَيۡهِۚ إِنَّهُۥ هُوَ ٱلتَّوَّابُ ٱلرَّحِيمُ ٣٧","فتلقى آدم من ربه كلمات فتاب عليه إنه هو التواب الرحيم","ފަހެ، އާދަމުގެފާނު، އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ކަލިމަ ފުޅުތަކެއް ބާވައިގަންނަވައި (އެ ކަލިމަފުޅުތައް ވިދާޅުވެ، ތައުބާ ވެވަޑައިގަތުމުން) ފަހެ، އެކަލާނގެ އެކަލޭގެފާނުގެ މައްޗަށް ތައުބާ ލައްވައިފިއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ގިނަގިނައިން ތައުބާ ގަބޫލުކުރައްވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","38","قُلۡنَا ٱهۡبِطُواْ مِنۡهَا جَمِيعٗاۖ فَإِمَّا يَأۡتِيَنَّكُم مِّنِّي هُدٗى فَمَن تَبِعَ هُدَايَ فَلَا خَوۡفٌ عَلَيۡهِمۡ وَلَا هُمۡ يَحۡزَنُونَ ٣٨","قلنا اهبطوا منها جميعا فإما يأتينكم مني هدى فمن تبع هداي فلا خوف عليهم ولا هم يحزنون","ތިމަންރަސްކަލާނގެ (އާދަމުގެފާނުގެ ދެކަނބަލުންނާއި އިބްލީސަށް) ވަހީކުރެއްވީމެވެ. ތިޔަބައިމީހުން އެންމެން އެ ސުވަރުގެއިން (ބިމަށް) ފައިބާށެވެ! ފަހެ، ތިޔަބައިމީހުންގެ ގާތަށް، ތިމަންރަސްކަލާނގެ ހަޒުރަތުން ތެދުމަގު އަތުވެއްޖެހިނދަކު، ތިމަންރަސްކަލާނގެ ތެދުމަގާ ތަބާ ވެއްޖެ ބަޔަކަށް އެއްވެސް ބިރެއްނެތެވެ. އަދި އެއުރެންނީ، ހިތާމަކުރާނޭ ބަޔަކު ކަމުގައިވެސް ނުމެވޭމެއެވެ.","",""],["₂ سورة البقرة","39","وَٱلَّذِينَ كَفَرُواْ وَكَذَّبُواْ بِـَٔايَٰتِنَآ أُوْلَـٰٓئِكَ أَصۡحَٰبُ ٱلنَّارِۖ هُمۡ فِيهَا خَٰلِدُونَ ٣٩","والذين كفروا وكذبوا بآياتنا أولئك أصحاب النار هم فيها خالدون","އަދި ކާފިރުވެ ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުޅަ މީހުންނީ، ނަރަކަވަންތަ ވެރިންނެވެ. އެއުރެންނީ، އެ ނަރަކައިގައި ދެމިތިބޭނޭ ބަޔެކެވެ.","",""],["₂ سورة البقرة","40","يَٰبَنِيٓ إِسۡرَـٰٓءِيلَ ٱذۡكُرُواْ نِعۡمَتِيَ ٱلَّتِيٓ أَنۡعَمۡتُ عَلَيۡكُمۡ وَأَوۡفُواْ بِعَهۡدِيٓ أُوفِ بِعَهۡدِكُمۡ وَإِيَّـٰيَ فَٱرۡهَبُونِ ٤٠","يا بني إسرائيل اذكروا نعمتي التي أنعمت عليكم وأوفوا بعهدي أوف بعهدكم وإياي فارهبون","އޭ އިސްރާއީލުގެދަރިންނޭވެ! ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް ދެއްވި ނިއުމަތް ތިޔަބައިމީހުން ހަނދުމަކުރާށެވެ! އަދި ތިމަންރަސްކަލާނގެ އަހުދު ތިޔަބައިމީހުން ފުއްދާށެވެ! (އެބަހީ: ތައުރާތުގައި ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް އަންގަވާފައިވާ އެންގެވުންތަކަށް ކިޔަމަންވެ، އެގޮތުގެމަތިން ޢަމަލުކުރާށެވެ!) އޭރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންގެ އަހުދު ފުއްދަވާހުށީމެވެ. (އެބަހީ: ކިޔަމަންގަތް އަޅުންނަށް ދެއްވާނެކަމަށް އަންގަވާފައިވާ ހެޔޮ ޖަޒާ ދެއްވާހުށީމެވެ.) އަދި ހަމައެކަނި ތިމަންރަސްކަލާނގެއަށް ތިޔަބައިމީހުން ބިރުވެތިވާށެވެ!","",""],["₂ سورة البقرة","41","وَءَامِنُواْ بِمَآ أَنزَلۡتُ مُصَدِّقٗا لِّمَا مَعَكُمۡ وَلَا تَكُونُوٓاْ أَوَّلَ كَافِرِۭ بِهِۦۖ وَلَا تَشۡتَرُواْ بِـَٔايَٰتِي ثَمَنٗا قَلِيلٗا وَإِيَّـٰيَ فَٱتَّقُونِ ٤١","وآمنوا بما أنزلت مصدقا لما معكم ولا تكونوا أول كافر به ولا تشتروا بآياتي ثمنا قليلا وإياي فاتقون","އަދި ތިޔަބައިމީހުންނާ އެކުގައިވާ ފޮތް (އެބަހީ: ތައުރާތު) ތެދުކުރަނިވި ގޮތުގައިވާ، ތިމަންރަސްކަލާނގެ ބާވައިލެއްވި ފޮތަށް (އެބަހީ: ގުރްއާނަށް) ތިޔަބައިމީހުން އީމާން ވާށެވެ! އަދި އެފޮތަށް އެންމެ ފުރަތަމައިން ކާފިރުވާ ބަޔަކު ކަމުގައި ތިޔަބައިމީހުން ނުވާށެވެ! އަދި ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް، ކުޑައަގެއް ތިޔަބައިމީހުން ނުގަންނާށެވެ! (އެބަހީ: ދުންޔަވީ އުފާތަކުގެ ތެރެއިން ތިމަންރަސްކަލާނގެ ހަރާމްކުރެއްވި ކަންތައްތައްފަދަ އެއްޗަކަށް ނުވާކަހަލަ އެއްޗަކަށްޓަކައި، ތިމަންރަސްކަލާނގެ އަންގަވާފައިވާ އެންގެވުންތަކަށް ފުރަގަސްނުދޭށެވެ!) އަދި ހަމައެކަނި ތިމަންރަސްކަލާނގެއަށް ތަގުވާވެރިވާށެވެ!","",""],["₂ سورة البقرة","42","وَلَا تَلۡبِسُواْ ٱلۡحَقَّ بِٱلۡبَٰطِلِ وَتَكۡتُمُواْ ٱلۡحَقَّ وَأَنتُمۡ تَعۡلَمُونَ ٤٢","ولا تلبسوا الحق بالباطل وتكتموا الحق وأنتم تعلمون","އަދި ތިޔަބައިމީހުން ހައްގާއި ބާތިލު އޮޅުވައިނުލާށެވެ! އަދި ތިޔަބައިމީހުން ދެނެތިބި ޙާލުގައި ހައްގު ވަންހަނާ ނުކުރާށެވެ!","",""],["₂ سورة البقرة","43","وَأَقِيمُواْ ٱلصَّلَوٰةَ وَءَاتُواْ ٱلزَّكَوٰةَ وَٱرۡكَعُواْ مَعَ ٱلرَّـٰ‌كِعِينَ ٤٣","وأقيموا الصلاة وآتوا الزكاة واركعوا مع الراكعين","އަދި ތިޔަބައިމީހުން ނަމާދު ގާއިމުކުރާށެވެ! އަދި ތިޔަބައިމީހުން ޒަކާތް ދޭށެވެ! އަދި ރުކޫއުކުރާ މީހުންނާ އެކުގައި ތިޔަބައިމީހުން ރުކޫއުކުރާށެވެ!","",""],["₂ سورة البقرة","44","۞أَتَأۡمُرُونَ ٱلنَّاسَ بِٱلۡبِرِّ وَتَنسَوۡنَ أَنفُسَكُمۡ وَأَنتُمۡ تَتۡلُونَ ٱلۡكِتَٰبَۚ أَفَلَا تَعۡقِلُونَ ٤٤","أتأمرون الناس بالبر وتنسون أنفسكم وأنتم تتلون الكتاب أفلا تعقلون","ތިޔަބައިމީހުން ފޮތް ކިޔަވަކިޔަވައި ތިބޭ ޙާލުގައި ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސު ތަކުގެމަތިން ހަނދާން ނައްތާލައި، މީސްތަކުންނަށް ހެޔޮކަންތަކަށް އަމުރުކުރަނީ ހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުން ނުވިސްނަނީ ހެއްޔެވެ؟","",""],["₂ سورة البقرة","45","وَٱسۡتَعِينُواْ بِٱلصَّبۡرِ وَٱلصَّلَوٰةِۚ وَإِنَّهَا لَكَبِيرَةٌ إِلَّا عَلَى ٱلۡخَٰشِعِينَ ٤٥","واستعينوا بالصبر والصلاة وإنها لكبيرة إلا على الخاشعين","އަދި ކެތްތެރިކަމާއި ނަމާދުން ތިޔަބައިމީހުން ވާގިހޯދާށެވެ! ބިރުވެތިވެ މަޑުމައިތިރިވާ މީހުންނަށް މެނުވީ، ހަމަކަށަވަރުން، އެއީ ވަރަށް ބޮޑުކަމެކެވެ. (އެބަހީ: ދަތި އުނދަގޫ ކަމެކެވެ.)","",""],["₂ سورة البقرة","46","ٱلَّذِينَ يَظُنُّونَ أَنَّهُم مُّلَٰقُواْ رَبِّهِمۡ وَأَنَّهُمۡ إِلَيۡهِ رَٰجِعُونَ ٤٦","الذين يظنون أنهم ملاقو ربهم وأنهم إليه راجعون","އެއުރެންނީ، އެއުރެންގެ ވެރިރަސްކަލާނގެއާ ބައްދަލުވާނޭ ބަޔަކުކަމާއި، އެކަލާނގެ ހަޒުރަތަށް އެނބުރި ރުޖޫއަ ވަނިވި ބަޔަކުކަން ކަށަވަރުކޮށް ޔަގީންކުރާ މީހުންނެވެ.","",""],["₂ سورة البقرة","47","يَٰبَنِيٓ إِسۡرَـٰٓءِيلَ ٱذۡكُرُواْ نِعۡمَتِيَ ٱلَّتِيٓ أَنۡعَمۡتُ عَلَيۡكُمۡ وَأَنِّي فَضَّلۡتُكُمۡ عَلَى ٱلۡعَٰلَمِينَ ٤٧","يا بني إسرائيل اذكروا نعمتي التي أنعمت عليكم وأني فضلتكم على العالمين","އޭ އިސްރާއީލުގެދަރިންނެވެ! ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް ދެއްވި ނިއުމަތާއި، އަދި (އެދުވަސްވަރުގެ) އާލަމްތަކުގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން މާތްކުރައްވާފައިވާކަން ހަނދުމަކުރާށެވެ!","",""],["₂ سورة البقرة","48","وَٱتَّقُواْ يَوۡمٗا لَّا تَجۡزِي نَفۡسٌ عَن نَّفۡسٖ شَيۡـٔٗا وَلَا يُقۡبَلُ مِنۡهَا شَفَٰعَةٞ وَلَا يُؤۡخَذُ مِنۡهَا عَدۡلٞ وَلَا هُمۡ يُنصَرُونَ ٤٨","واتقوا يوما لا تجزي نفس عن نفس شيئا ولا يقبل منها شفاعة ولا يؤخذ منها عدل ولا هم ينصرون","އެދުވަހަކުން އެއްވެސް ނަފްސަކަށް އެއްވެސް ނަފްސެއްގެ ކިބައިން ކަމެއް ފުއްދައިނުދެވޭނޭ، އަދި އެކެއްގެ ކިބައިން އަނެކެއްގެ ޝަފާއަތް ގަބޫލު ނުކުރައްވާނޭ، އަދި އެކެއްގެ ކިބައިން ފިދުޔެއްވެސް ނުހިއްޕަވާނޭ، އަދި އެއުރެންނަށް އެއްވެސް ފަރާތަކުން ނަސްރެއް ނުލިބޭނޭ ދުވަހަކަށް ތިޔަބައިމީހުން ބިރުވެތިވެ، ރައްކާތެރިވާށެވެ!","",""],["₂ سورة البقرة","49","وَإِذۡ نَجَّيۡنَٰكُم مِّنۡ ءَالِ فِرۡعَوۡنَ يَسُومُونَكُمۡ سُوٓءَ ٱلۡعَذَابِ يُذَبِّحُونَ أَبۡنَآءَكُمۡ وَيَسۡتَحۡيُونَ نِسَآءَكُمۡۚ وَفِي ذَٰلِكُم بَلَآءٞ مِّن رَّبِّكُمۡ عَظِيمٞ ٤٩","وإذ نجيناكم من آل فرعون يسومونكم سوء العذاب يذبحون أبناءكم ويستحيون نساءكم وفي ذلكم بلاء من ربكم عظيم","އަދި ފިރްޢައުނުގެ މީހުންގެ ކިބައިން ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން ސަލާމަތް ކުރެއްވިހިނދު، ހަނދުމަކުރާށެވެ! އެއުރެން، ތިޔަބައިމީހުންނަށް ގަދަފަދަވެގެންވާ އަޒާބުގެ ރަހަ ދައްކަމުންގެންދެއެވެ. އެއުރެން ތިޔަބައިމީހުންގެ ފިރިހެންދަރިން ކަތިލައި، އަދި ތިޔަބައިމީހުންގެ އަންހެންދަރިން ނުމަރައި ބައިތިއްބަތެވެ. އެކަންތައްތަކުގައި، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައިސްފައިވާ ބޮޑު އިމްތިހާނެއް ވެއެވެ.","",""],["₂ سورة البقرة","50","وَإِذۡ فَرَقۡنَا بِكُمُ ٱلۡبَحۡرَ فَأَنجَيۡنَٰكُمۡ وَأَغۡرَقۡنَآ ءَالَ فِرۡعَوۡنَ وَأَنتُمۡ تَنظُرُونَ ٥٠","وإذ فرقنا بكم البحر فأنجيناكم وأغرقنا آل فرعون وأنتم تنظرون","އަދި ތިޔަބައިމީހުންނަށް، ތިމަންރަސްކަލާނގެ ކަނޑު އިރުއްވައި ދެއްވިހިނދު، ހަނދުމަކުރާށެވެ! ފަހެ، ތިމަންރަސްކަލާނގެ، ތިޔަބައިމީހުން (ޣަރަގުން) ސަލާމަތްކުރައްވައި، ތިޔަބައިމީހުން ބަލަބަލައިތިއްބައި، ފިރްޢައުނުގެ މީހުން ޣަރަގުކުރެއްވީމެވެ.","",""],["₂ سورة البقرة","51","وَإِذۡ وَٰعَدۡنَا مُوسَىٰٓ أَرۡبَعِينَ لَيۡلَةٗ ثُمَّ ٱتَّخَذۡتُمُ ٱلۡعِجۡلَ مِنۢ بَعۡدِهِۦ وَأَنتُمۡ ظَٰلِمُونَ ٥١","وإذ واعدنا موسى أربعين ليلة ثم اتخذتم العجل من بعده وأنتم ظالمون","އަދި މޫސާގެފާނަށް، ތިމަންރަސްކަލާނގެ ސާޅީސް ރޭގެ މީޢާދެއް ކަނޑައެޅުއްވިހިނދު، ހަނދުމަކުރާށެވެ! ދެން އެއަށްފަހު (ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތަކަށް) ތިޔަބައިމީހުން އަނިޔާވެރިވާ ޙާލުގައި ގެރިއަކީ އިލާހަކު ކަމުގައި ހަދައިގެން އުޅުނީމުއެވެ.","",""],["₂ سورة البقرة","52","ثُمَّ عَفَوۡنَا عَنكُم مِّنۢ بَعۡدِ ذَٰلِكَ لَعَلَّكُمۡ تَشۡكُرُونَ ٥٢","ثم عفونا عنكم من بعد ذلك لعلكم تشكرون","ދެން އެކަންތަކަށް ފަހުގައި (އެކަމުގެ ކުށް) ތިޔަބައިމީހުންގެ ކިބައިން ތިމަންރަސްކަލާނގެ އަފޫކުރެއްވީމެވެ. (އެއީ) ތިޔަބައިމީހުން ޝުކުރުވެރިވުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","53","وَإِذۡ ءَاتَيۡنَا مُوسَى ٱلۡكِتَٰبَ وَٱلۡفُرۡقَانَ لَعَلَّكُمۡ تَهۡتَدُونَ ٥٣","وإذ آتينا موسى الكتاب والفرقان لعلكم تهتدون","އަދި ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް ހައްގާއި ބާތިލު ވަކިކުރަނިވި ފޮތް (އެބަހީ: ތައުރާތު) ދެއްވިހިނދު، ހަނދުމަކުރާށެވެ! (އެއީ) ތިޔަބައިމީހުން، އެއިން ތެދުމަގު ލިބިގަތުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","54","وَإِذۡ قَالَ مُوسَىٰ لِقَوۡمِهِۦ يَٰقَوۡمِ إِنَّكُمۡ ظَلَمۡتُمۡ أَنفُسَكُم بِٱتِّخَاذِكُمُ ٱلۡعِجۡلَ فَتُوبُوٓاْ إِلَىٰ بَارِئِكُمۡ فَٱقۡتُلُوٓاْ أَنفُسَكُمۡ ذَٰلِكُمۡ خَيۡرٞ لَّكُمۡ عِندَ بَارِئِكُمۡ فَتَابَ عَلَيۡكُمۡۚ إِنَّهُۥ هُوَ ٱلتَّوَّابُ ٱلرَّحِيمُ ٥٤","وإذ قال موسى لقومه يا قوم إنكم ظلمتم أنفسكم باتخاذكم العجل فتوبوا إلى بارئكم فاقتلوا أنفسكم ذلكم خير لكم عند بارئكم فتاب عليكم إنه هو التواب الرحيم","އަދި މޫސާގެފާނު، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ގާތުގައި (މިފަދައިން) ވިދާޅުވިހިނދު (ހަނދުމަކުރާށެވެ!) އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން، ގެރިއަކީ އިލާހަކު ކަމުގައި ހެދުމުން، ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތަކަށް ތިޔަބައިމީހުން އަނިޔާވެރިވެއްޖެކަން ކަށަވަރެވެ. ފަހެ، ތިޔަބައިމީހުން އުފެއްދެވި ކަލާނގެއަށް ތައުބާ ވާށެވެ! އަދި ތިޔަބައިމީހުންގެ ނަފްސުތައް ގަތުލުކުރާށެވެ! ތިޔަބައިމީހުން އުފެއްދެވި ކަލާނގެ ހަޒުރަތުގައި، އެގޮތް ތިޔަބައިމީހުންނަށް ހެޔޮކަން ބޮޑެވެ. ދެން އެކަލާނގެ ތިޔަބައިމީހުންގެ މައްޗަށް ތައުބާ ލެއްވިއެވެ. ހަމަކަށަވަރުން އެކަލާނގެއީ، ގިނަގިނައިން ތައުބާ ގަބޫލުކުރައްވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","55","وَإِذۡ قُلۡتُمۡ يَٰمُوسَىٰ لَن نُّؤۡمِنَ لَكَ حَتَّىٰ نَرَى ٱللَّهَ جَهۡرَةٗ فَأَخَذَتۡكُمُ ٱلصَّـٰعِقَةُ وَأَنتُمۡ تَنظُرُونَ ٥٥","وإذ قلتم يا موسى لن نؤمن لك حتى نرى الله جهرة فأخذتكم الصاعقة وأنتم تنظرون","އަދި އޭ މޫސާގެފާނެވެ! ފާޅުގައި އަހަރެމެން ﷲ ދެކެފުމަށްދާނދެން އަހަރެމެން ކަލޭގެފާނަކަށް އީމާނެއް ނުވާނޫއޭ ތިޔަބައިމީހުން ދެންނެވިހިނދު، ހަނދުމަކުރާށެވެ! ދެން ތިޔަބައިމީހުން ބަލަބަލައިތިއްބައި، ހޮނުގުގުރި ތިޔަބައިމީހުންގެ މަރު ހިފައިފިއެވެ.","",""],["₂ سورة البقرة","56","ثُمَّ بَعَثۡنَٰكُم مِّنۢ بَعۡدِ مَوۡتِكُمۡ لَعَلَّكُمۡ تَشۡكُرُونَ ٥٦","ثم بعثناكم من بعد موتكم لعلكم تشكرون","ދެން ތިޔަބައިމީހުން މަރުވުމަށްފަހު، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން އަލުން ދިރުއްވީމެވެ. (އެއީ) ތިޔަބައިމީހުން ޝުކުރުވެރިވުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","57","وَظَلَّلۡنَا عَلَيۡكُمُ ٱلۡغَمَامَ وَأَنزَلۡنَا عَلَيۡكُمُ ٱلۡمَنَّ وَٱلسَّلۡوَىٰۖ كُلُواْ مِن طَيِّبَٰتِ مَا رَزَقۡنَٰكُمۡۚ وَمَا ظَلَمُونَا وَلَٰكِن كَانُوٓاْ أَنفُسَهُمۡ يَظۡلِمُونَ ٥٧","وظللنا عليكم الغمام وأنزلنا عليكم المن والسلوى كلوا من طيبات ما رزقناكم وما ظلمونا ولكن كانوا أنفسهم يظلمون","އަދި ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންގެ މައްޗަށް އެ ވިލާގަނޑުން ހިޔާ އެޅުއްވީމެވެ. އަދި ތިޔަބައިމީހުންގެ މައްޗަށް މައްނާއި ސަލްވާ ބާވައިލެއްވީމެވެ. ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް ދެއްވި ހަލާލު ތަކެތިން ތިޔަބައިމީހުން ކައިއުޅޭށޭ އެންގެވީމެވެ. އެއުރެން އެ ނިއުމަތަށް ކާފިރުވެ، އުރެދުމަކުން އެއުރެންނަކަށް ތިމަންރަސްކަލާނގެއަކަށް އަނިޔާއެއް ނުކުރެވުނެވެ. އެހެނެއްކަމަކު، އެއުރެން އަނިޔާކުރާ ކަމުގައިވީ، ހަމައެކަނި އެއުރެންގެ އަމިއްލަ ނަފްސު ތަކަށެވެ. (ނޯޓު: މައްނަކީ ބައެއް މުފައްސިރުން ވިދާޅުވާ ގޮތުގައި ފިނިފައިބާގޮތަށް ފައިބާ އެއްޗެކެވެ. އެއީ މާމުއިކަހަލަ ފޮނި އެއްޗެކެވެ. އަނެއްބައި މުފައްސިރުން ވިދާޅުވާ ގޮތުގައި، އެއީ ގަނޑުފެނާ އެއްފަދަ، މާމުޔަށްވުރެ ފޮނި، ކިރަށްވުރެ ހުދު އެއްޗެކެވެ. ސަލްވާއަކީ، ބާވަތެއްގެ ދޫންޏެކެވެ.)","",""],["₂ سورة البقرة","58","وَإِذۡ قُلۡنَا ٱدۡخُلُواْ هَٰذِهِ ٱلۡقَرۡيَةَ فَكُلُواْ مِنۡهَا حَيۡثُ شِئۡتُمۡ رَغَدٗا وَٱدۡخُلُواْ ٱلۡبَابَ سُجَّدٗا وَقُولُواْ حِطَّةٞ نَّغۡفِرۡ لَكُمۡ خَطَٰيَٰكُمۡۚ وَسَنَزِيدُ ٱلۡمُحۡسِنِينَ ٥٨","وإذ قلنا ادخلوا هذه القرية فكلوا منها حيث شئتم رغدا وادخلوا الباب سجدا وقولوا حطة نغفر لكم خطاياكم وسنزيد المحسنين","އަދި ތިޔަބައިމީހުން މިއޮތް ރަށަށް ވަންނާށޭ ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވި ހިނދު، ހަނދުމަކުރާށެވެ! ފަހެ، ތަނަވަސްކަމާއެކުގައި ތިޔަބައިމީހުން އެދޭ ފަދައަކުން އެރަށުން ކައިއުޅޭށެވެ! އަދި ތިޔަބައިމީހުން ސަޖިދަކުރާ ޙާލު (އެބަހީ: މަޑުމައިތިރިވެ، ކިޔަމަންވެގެންވާ ޙާލު އެރަށުގެ) ދޮރޯށިން ވަންނާށެވެ! އަދި އަޅަމެންގެ އެދުމަކީ ކުށްފާފަތައް ފުއްސަވައި އަފޫކުރެއްވުމޭ ދަންނަވާށެވެ! އޭރުން ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް ތިޔަބައިމީހުންގެ ކުށްފާފަތައް ފުއްސަވާހުށީމެވެ. އަދި އިހްސާން ތެރިންނަށް ތިމަންރަސްކަލާނގެ (ހެޔޮކަން) އިތުރު ކުރައްވާހުށީމެވެ.","",""],["₂ سورة البقرة","59","فَبَدَّلَ ٱلَّذِينَ ظَلَمُواْ قَوۡلًا غَيۡرَ ٱلَّذِي قِيلَ لَهُمۡ فَأَنزَلۡنَا عَلَى ٱلَّذِينَ ظَلَمُواْ رِجۡزٗا مِّنَ ٱلسَّمَآءِ بِمَا كَانُواْ يَفۡسُقُونَ ٥٩","فبدل الذين ظلموا قولا غير الذي قيل لهم فأنزلنا على الذين ظلموا رجزا من السماء بما كانوا يفسقون","ދެން (އޭގެތެރެއިން) އަނިޔާވެރިވި މީހުން، އެއުރެންނަށް ކިޔާށޭ އެންގެވި ބަސް އެނޫން ބަހަކަށް ބަދަލުކޮށްފޫއެވެ. ދެން އެ އަނިޔާވެރިވި މީހުންގެ މައްޗަށް، އެއުރެން ފާސިގުވި ކަމުގެ ސަބަބުން، އުޑުން އަޒާބެއް ތިމަންރަސްކަލާނގެ ބާވައިލެއްވީމެވެ.","",""],["₂ سورة البقرة","60","۞وَإِذِ ٱسۡتَسۡقَىٰ مُوسَىٰ لِقَوۡمِهِۦ فَقُلۡنَا ٱضۡرِب بِّعَصَاكَ ٱلۡحَجَرَۖ فَٱنفَجَرَتۡ مِنۡهُ ٱثۡنَتَا عَشۡرَةَ عَيۡنٗاۖ قَدۡ عَلِمَ كُلُّ أُنَاسٖ مَّشۡرَبَهُمۡۖ كُلُواْ وَٱشۡرَبُواْ مِن رِّزۡقِ ٱللَّهِ وَلَا تَعۡثَوۡاْ فِي ٱلۡأَرۡضِ مُفۡسِدِينَ ٦٠","وإذ استسقى موسى لقومه فقلنا اضرب بعصاك الحجر فانفجرت منه اثنتا عشرة عينا قد علم كل أناس مشربهم كلوا واشربوا من رزق الله ولا تعثوا في الأرض مفسدين","މޫސާގެފާނު އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށްޓަކައި ފެނަށް އެދިވަޑައިގެން ދުއާކުރެއްވިހިނދު، ހަނދުމަކުރާށެވެ! ފަހެ، (އެހިނދު މޫސާގެފާނަށް) ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވީމެވެ. ކަލޭގެފާނުގެ އަސާކޮޅުން، ކަލޭގެފާނު އެ ހިލައިގައި ޖައްސަވާށެވެ! ދެން (އެކަލޭގެފާނު އެހިލައިގައި ޖެއްސެވިހިނދު) އެހިލައިން ބާރަ ފެންއާރު އަރައިގެންފިއެވެ. ހަމަކަށަވަރުން ކޮންމެބަޔަކު، އެބަޔަކު ފެންބޯންވީ ޖާގަ ދެނެގެންފިއެވެ. (އަދި ތިމަންރަސްކަލާނގެ އެންގެވީމެވެ.) ތިޔަބައިމީހުން، ﷲ ދެއްވި ރިޒްގުން ކައިބޮއި އުޅޭށެވެ! އަދި ފާސިދުން ކަމުގައިވެތިބެ، ތިޔަބައިމީހުން ބިމުގައި ފަސާދަ ނުކުރާށެވެ!","",""],["₂ سورة البقرة","61","وَإِذۡ قُلۡتُمۡ يَٰمُوسَىٰ لَن نَّصۡبِرَ عَلَىٰ طَعَامٖ وَٰحِدٖ فَٱدۡعُ لَنَا رَبَّكَ يُخۡرِجۡ لَنَا مِمَّا تُنۢبِتُ ٱلۡأَرۡضُ مِنۢ بَقۡلِهَا وَقِثَّآئِهَا وَفُومِهَا وَعَدَسِهَا وَبَصَلِهَاۖ قَالَ أَتَسۡتَبۡدِلُونَ ٱلَّذِي هُوَ أَدۡنَىٰ بِٱلَّذِي هُوَ خَيۡرٌۚ ٱهۡبِطُواْ مِصۡرٗا فَإِنَّ لَكُم مَّا سَأَلۡتُمۡۗ وَضُرِبَتۡ عَلَيۡهِمُ ٱلذِّلَّةُ وَٱلۡمَسۡكَنَةُ وَبَآءُو بِغَضَبٖ مِّنَ ٱللَّهِۗ ذَٰلِكَ بِأَنَّهُمۡ كَانُواْ يَكۡفُرُونَ بِـَٔايَٰتِ ٱللَّهِ وَيَقۡتُلُونَ ٱلنَّبِيِّـۧنَ بِغَيۡرِ ٱلۡحَقِّۗ ذَٰلِكَ بِمَا عَصَواْ وَّكَانُواْ يَعۡتَدُونَ ٦١","وإذ قلتم يا موسى لن نصبر على طعام واحد فادع لنا ربك يخرج لنا مما تنبت الأرض من بقلها وقثائها وفومها وعدسها وبصلها قال أتستبدلون الذي هو أدنى بالذي هو خير اهبطوا مصرا فإن لكم ما سألتم وضربت عليهم الذلة والمسكنة وباءوا بغضب من الله ذلك بأنهم كانوا يكفرون بآيات الله ويقتلون النبيين بغير الحق ذلك بما عصوا وكانوا يعتدون","އަދި ތިޔަބައިމީހުން (މިފަދައިން) ދެންނެވިހިނދު، ހަނދުމަކުރާށެވެ! އޭ މޫސާގެފާނެވެ! އެއްބާވަތެއްގެ ކާނާއެއްގެ މައްޗަކަށް ތިމަންމެންނަކަށް ކެތެއް ނުކުރެވޭނެތެވެ. ފަހެ، ބިމުން ފަޅާ ގަސްގަހާގެހީގެ ތެރެއިން އޮށްޓަރުގެ ބާވަތްތަކާއި، ގިއްޘާ (އެބަހީ: ކެކުރި ވައްތަރުގެ ތަރުކާރީއެއް) އާއި، ލޮނުމެދާއި، މުގާއި، ފިޔާ، ތިމަންމެންނަށްޓަކައި ނެރުއްވައި ދެއްވުމަށް ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ދުއާ ކޮށްދެއްވާށެވެ! އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން މޮޅު ތަކެތީގެ ބަދަލުގައި ދެރަ ތަކެއްޗަށް އެދެނީ ހެއްޔެވެ؟ (އެގޮތް އެދެނީނަމަ) ތިޔަބައިމީހުން ބޮޑު ރަށަކަށް ފައިބާށެވެ! އޭރުން، ހަމަކަށަވަރުން ތިޔަބައިމީހުން އެދުނު ތަކެތި ލިބޭހުށްޓެވެ. ދެރަކަމާއި ނިކަމެތިކަން އެއުރެންނަށް ޖެހުނެވެ. އަދި ﷲގެ ކޯފާ އެއުރެންގެމައްޗަށް ހައްގުވެ، އެ ކޯފާއާއިގެން އެއުރެން އެނބުރިއައޫއެވެ. އެއީ، ހަމަކަށަވަރުން އެއުރެން ﷲގެ އާޔަތްތަކަށް ކާފިރުވެ، ހައްގަކާ ނުލައި ނަބީބޭކަލުން ގަތުލުކުރާ ބަޔަކު ކަމުގައިވީތީއެވެ. އެއީ، އެއުރެން އުރެދިގަނެ، އެކަމުގައި ހައްދުފަހަނަޅައި ދާކަމުގައި އެއުރެން ވިކަމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","62","إِنَّ ٱلَّذِينَ ءَامَنُواْ وَٱلَّذِينَ هَادُواْ وَٱلنَّصَٰرَىٰ وَٱلصَّـٰبِـِٔينَ مَنۡ ءَامَنَ بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِ وَعَمِلَ صَٰلِحٗا فَلَهُمۡ أَجۡرُهُمۡ عِندَ رَبِّهِمۡ وَلَا خَوۡفٌ عَلَيۡهِمۡ وَلَا هُمۡ يَحۡزَنُونَ ٦٢","إن الذين آمنوا والذين هادوا والنصارى والصابئين من آمن بالله واليوم الآخر وعمل صالحا فلهم أجرهم عند ربهم ولا خوف عليهم ولا هم يحزنون","ހަމަކަށަވަރުން އީމާން ވެއްޖެ މީސްތަކުންނާއި، ޔަހޫދީން ކަމުގައިވި މީހުންނާއި، ނަސާރާ އިންނާއި، ޞާބިއްނާއި (މިއެންމެންގެ ތެރެއިންވެސް) ﷲއަށާއި އާޚިރަތް ދުވަހަށް އީމާންވެ، ސާލިހު ޢަމަލުކުޅަ މީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި، އެއުރެންގެ ދަރުމަ، އެއުރެންނަށް ހުށްޓެވެ. އަދި އެއުރެންގެ މައްޗަކަށް އެއްވެސް ބިރެއް ނެތެވެ. އަދި އެއުރެންނީ، ހިތާމަކުރާ ބަޔަކު ކަމުގައިވެސް ނުމެވޭމެއެވެ. (ނޯޓު: ޞާބިއުންނަކީ ދީނެއްނެތް މީހުން ކަމަށާއި، ތަރިތަކަށާއި، މަލާއިކަތުންނަށް އަޅުކަންކުރާ މީހުން ކަމަށް ބުނެވެއެވެ.)","",""],["₂ سورة البقرة","63","وَإِذۡ أَخَذۡنَا مِيثَٰقَكُمۡ وَرَفَعۡنَا فَوۡقَكُمُ ٱلطُّورَ خُذُواْ مَآ ءَاتَيۡنَٰكُم بِقُوَّةٖ وَٱذۡكُرُواْ مَا فِيهِ لَعَلَّكُمۡ تَتَّقُونَ ٦٣","وإذ أخذنا ميثاقكم ورفعنا فوقكم الطور خذوا ما آتيناكم بقوة واذكروا ما فيه لعلكم تتقون","ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންގެ ކިބައިން ކަށަވަރުވެގެންވާ އަހުދު ހިއްޕަވައި، ތިޔަބައިމީހުންގެ (ބޮލާދިމާ) މައްޗަށް ޠޫރު ފަރުބަދަ އުފުއްލެވި ހިނދު، ހަނދުމަކުރާށެވެ! (އެހިނދު ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް އެންގެވީމެވެ.) ތިޔަބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ ދެއްވި އެއްޗެއްގައި (އެބަހީ: ތިމަންރަސްކަލާނގެ ފޮތުގައި) ތިޔަބައިމީހުން ގަދަޔަށް ހިފަހައްޓާށެވެ! އަދި އެފޮތުގައިވާ ގޮތް ތިޔަބައިމީހުން ހަނދުމަ ކުރާށެވެ! (އެއީ) ތިޔަބައިމީހުން ތަގުވާވެރިވުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","64","ثُمَّ تَوَلَّيۡتُم مِّنۢ بَعۡدِ ذَٰلِكَۖ فَلَوۡلَا فَضۡلُ ٱللَّهِ عَلَيۡكُمۡ وَرَحۡمَتُهُۥ لَكُنتُم مِّنَ ٱلۡخَٰسِرِينَ ٦٤","ثم توليتم من بعد ذلك فلولا فضل الله عليكم ورحمته لكنتم من الخاسرين","ދެން އޭގެފަހުން ތިޔަބައިމީހުން (އެ އަހުދަށް) ފުރަގަސްދީ، އެނބުރި ހިނގައްޖައީމުއެވެ. ފަހެ، ﷲގެ ފަޟްލު ވަންތަކަމާއި، އެކަލާނގެ ރަހުމަތް ވަންތަކަން، ތިޔަބައިމީހުންގެމައްޗަށް ނުވާނަމަ، ގެއްލެނިވެގެންވާ މީހުންގެ ތެރެއިން ތިޔަބައިމީހުން ވީސްކަން ކަށަވަރެވެ.","",""],["₂ سورة البقرة","65","وَلَقَدۡ عَلِمۡتُمُ ٱلَّذِينَ ٱعۡتَدَوۡاْ مِنكُمۡ فِي ٱلسَّبۡتِ فَقُلۡنَا لَهُمۡ كُونُواْ قِرَدَةً خَٰسِـِٔينَ ٦٥","ولقد علمتم الذين اعتدوا منكم في السبت فقلنا لهم كونوا قردة خاسئين","އަދި ތިޔަބައިމީހުންގެ ތެރެއިން، ހޮނިހިރުދުވަހާމެދު (ދެކޮޅުވެރިވެ، ނުކިޔަމަންތެރިވުމުގައި) ހައްދުފަހަނަޅައިދިޔަ މީހުންގެ ވާހަކަ، ތިޔަބައިމީހުންނަށް އެނގިފައިވާކަން ކަށަވަރެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ، އެއުރެންނަށް އެންގެވީމެވެ. ތިޔަބައިމީހުން ދެރަވެ، ނިކަމެތި ވެގެންވާ ރާމާމަކުނުތަކަކަށް ވާށެވެ!","",""],["₂ سورة البقرة","66","فَجَعَلۡنَٰهَا نَكَٰلٗا لِّمَا بَيۡنَ يَدَيۡهَا وَمَا خَلۡفَهَا وَمَوۡعِظَةٗ لِّلۡمُتَّقِينَ ٦٦","فجعلناها نكالا لما بين يديها وما خلفها وموعظة للمتقين","ފަހެ، އެކަންތަކުގެ ކުރިމަތީގައިވާ މީހުންނަށާއި، އޭގެފަހުން އަންނާނޭ މީހުންނަށް ވަރުގަދަ އިބްރަތެއް ކަމުގައްޔާއި، ތަގުވާވެރިންނަށް ފުރިހަމަ ނަސޭހަތެއް ކަމުގައި ތިމަންރަސްކަލާނގެ އެކަންތައް ލެއްވީމެވެ.","",""],["₂ سورة البقرة","67","وَإِذۡ قَالَ مُوسَىٰ لِقَوۡمِهِۦٓ إِنَّ ٱللَّهَ يَأۡمُرُكُمۡ أَن تَذۡبَحُواْ بَقَرَةٗۖ قَالُوٓاْ أَتَتَّخِذُنَا هُزُوٗاۖ قَالَ أَعُوذُ بِٱللَّهِ أَنۡ أَكُونَ مِنَ ٱلۡجَٰهِلِينَ ٦٧","وإذ قال موسى لقومه إن الله يأمركم أن تذبحوا بقرة قالوا أتتخذنا هزوا قال أعوذ بالله أن أكون من الجاهلين","އަދި މޫސާގެފާނު އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ގާތުގައި (މިފަދައިން) ވިދާޅުވިހިނދު، (ހަނދުމަކުރާށެވެ!) ތިޔަބައިމީހުން ގެރިއެއް ކަތިލުމަށް ހަމަކަށަވަރުން ﷲ، ތިޔަބައިމީހުންނަށް އަމުރުކުރައްވަތެވެ. އެއުރެން ދެންނެވޫއެވެ. ފުރައްސާރަކުރެވޭ ބަޔަކު ކަމުގައި ކަލޭގެފާނު ތިމަންމެން ހައްދަވަނީތޯއެވެ؟ އެކަލޭގެފާނު ވިދާޅުވިއެވެ. (އެފަދަ ކަންތައްކުރާ) ޖާހިލުންގެ ތެރެއިން، (ވެވަޑައިނުގަތުންއެދި) ތިމަންކަލޭގެފާނު ﷲގެ ހަޒުރަތުން ރައްކާތެރިކަން ލިބިވަޑައިގަންނަވަމެވެ.","",""],["₂ سورة البقرة","68","قَالُواْ ٱدۡعُ لَنَا رَبَّكَ يُبَيِّن لَّنَا مَا هِيَۚ قَالَ إِنَّهُۥ يَقُولُ إِنَّهَا بَقَرَةٞ لَّا فَارِضٞ وَلَا بِكۡرٌ عَوَانُۢ بَيۡنَ ذَٰلِكَۖ فَٱفۡعَلُواْ مَا تُؤۡمَرُونَ ٦٨","قالوا ادع لنا ربك يبين لنا ما هي قال إنه يقول إنها بقرة لا فارض ولا بكر عوان بين ذلك فافعلوا ما تؤمرون","އެއުރެން ދެންނެވޫއެވެ. އެއީ ކޮންކަހަލަ ގެރިއެއްކަން އަޅުގަނޑުމެންނަށް ބަޔާންކޮށްދެއްވުމަށް ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ދަންނަވައިދެއްވާށެވެ! އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެ ވަހީކުރައްވައި އަންގަވަތެވެ. ހަމަކަށަވަރުން އެއީ، ދުވަސްވެ މުސްކުޅިވެފައިވާ ގެރިއެއް ނޫނެވެ. ޅަގެރިއެއްވެސް ނޫނެވެ. އެ ދެމެދުގެ ގެރިއެކެވެ. ފަހެ، ތިޔަބައިމީހުންނަށް އަމުރުކުރައްވާ ކަންތައް ތިޔަބައިމީހުން ކުރާށެވެ!","",""],["₂ سورة البقرة","69","قَالُواْ ٱدۡعُ لَنَا رَبَّكَ يُبَيِّن لَّنَا مَا لَوۡنُهَاۚ قَالَ إِنَّهُۥ يَقُولُ إِنَّهَا بَقَرَةٞ صَفۡرَآءُ فَاقِعٞ لَّوۡنُهَا تَسُرُّ ٱلنَّـٰظِرِينَ ٦٩","قالوا ادع لنا ربك يبين لنا ما لونها قال إنه يقول إنها بقرة صفراء فاقع لونها تسر الناظرين","އެއުރެން ދެންނެވޫއެވެ. އެ ގެރީގެ ކުލައަކީ ކޮބައިކަން އަޅުގަނޑުމެންނަށް ބަޔާންކޮށްދެއްވުމަށް، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ދަންނަވައިދެއްވާށެވެ! އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެ ވަހީކުރައްވައި އަންގަވަތެވެ. އެއީ، ހަމަކަށަވަރުން ބަލާމީހުންނަށް އުފާވެރިކަން ދެނިވި، ރީނދޫކުލައިގެ ކުލަގަދަ ގެރިއެކެވެ.","",""],["₂ سورة البقرة","70","قَالُواْ ٱدۡعُ لَنَا رَبَّكَ يُبَيِّن لَّنَا مَا هِيَ إِنَّ ٱلۡبَقَرَ تَشَٰبَهَ عَلَيۡنَا وَإِنَّآ إِن شَآءَ ٱللَّهُ لَمُهۡتَدُونَ ٧٠","قالوا ادع لنا ربك يبين لنا ما هي إن البقر تشابه علينا وإنا إن شاء الله لمهتدون","އެއުރެން ދެންނެވޫއެވެ. އެއީ ކޮން ގެރިއެއްކަން އަޅުގަނޑުމެންނަށް ބަޔާންކޮށްދެއްވުމަށް، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ދަންނަވައިދެއްވާށެވެ! (އެހެނީ) ހަމަކަށަވަރުން (ތިޔަ ސިފަކުރައްވާ) ގެރި އަޅުގަނޑުމެންނަށް އޮޅިއްޖެއެވެ. ﷲ އިރާދަކުރެއްވިއްޔާ ހަމަކަށަވަރުން ތިމަންމެން ވާހުށީ (އެކަމަށް) ތެދުމަގު ލިބިގެންވާ ބަޔަކު ކަމުގައެވެ.","",""],["₂ سورة البقرة","71","قَالَ إِنَّهُۥ يَقُولُ إِنَّهَا بَقَرَةٞ لَّا ذَلُولٞ تُثِيرُ ٱلۡأَرۡضَ وَلَا تَسۡقِي ٱلۡحَرۡثَ مُسَلَّمَةٞ لَّا شِيَةَ فِيهَاۚ قَالُواْ ٱلۡـَٰٔنَ جِئۡتَ بِٱلۡحَقِّۚ فَذَبَحُوهَا وَمَا كَادُواْ يَفۡعَلُونَ ٧١","قال إنه يقول إنها بقرة لا ذلول تثير الأرض ولا تسقي الحرث مسلمة لا شية فيها قالوا الآن جئت بالحق فذبحوها وما كادوا يفعلون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެ ވަހީކުރައްވައި އަންގަވަތެވެ. ހަމަކަށަވަރުން އެއީ، ދަނޑުބިމުގެ ފަސްގަނޑުޖަހާ ނިކަމެތި ގެރިއެއް ނޫނެވެ. އަދި ދަނޑަށް ފެންދޭ ގެރިއެއްވެސް ނޫނެވެ. (އައިބު ތަކުން) ސަލާމަތް ވެގެންވާ، އޭގައި އެއްވެސް ލަފެއްނެތް ގެރިއެކެވެ. އެއުރެން ދެންނެވޫއެވެ. މިހާރު ކަލޭގެފާނު އޮޅުމެއްނެތް ސާފުބަޔާން ގެނެސްދެއްވައިފީމުއެވެ. ދެން އެއުރެން އެ ގެރި ކަތިލައިފޫއެވެ. އެއުރެންތިބީ، އެކަން ކުރާހިތަކުން ނޫނެވެ.","",""],["₂ سورة البقرة","72","وَإِذۡ قَتَلۡتُمۡ نَفۡسٗا فَٱدَّـٰرَٰٔتُمۡ فِيهَاۖ وَٱللَّهُ مُخۡرِجٞ مَّا كُنتُمۡ تَكۡتُمُونَ ٧٢","وإذ قتلتم نفسا فادارأتم فيها والله مخرج ما كنتم تكتمون","ތިޔަބައިމީހުން މީހަކު މަރާލާފައި، އެ މަރާމެދު ދެބަސްވެ ޚިލާފު ވިހިނދު، ހަނދުމަކުރާށެވެ! ތިޔަބައިމީހުން ވަންހަނާކޮށްއުޅުނު ކަންތައް، ﷲ ހާމަކުރައްވައި، ނެރުއްވާހުށްޓެވެ.","",""],["₂ سورة البقرة","73","فَقُلۡنَا ٱضۡرِبُوهُ بِبَعۡضِهَاۚ كَذَٰلِكَ يُحۡيِ ٱللَّهُ ٱلۡمَوۡتَىٰ وَيُرِيكُمۡ ءَايَٰتِهِۦ لَعَلَّكُمۡ تَعۡقِلُونَ ٧٣","فقلنا اضربوه ببعضها كذلك يحيي الله الموتى ويريكم آياته لعلكم تعقلون","ދެން ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވީމެވެ. އޭގެ (އެބަހީ: އެ ކަތިލި ގެރީގެ) އެތިކޮޅަކުން، އެ (މަރުވެފައިވާ) މީހާގެ ގައިގައި ތިޔަބައިމީހުން ޖަހާށެވެ! (ދެން އެއުރެން ޖެހި ހިނދު، އެމީހާ އަލުން ދިރިއްޖެއެވެ.) މަރުވެފައިވާ ތަކެތި، ﷲ އަލުން ދިރުއްވަނީ އެފަދައިންނެވެ. އަދި ތިޔަބައިމީހުންނަށް، އެކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެކިތައް ދައްކަވަނީވެސް، އެފަދައިންނެވެ. (އެއީ) ތިޔަބައިމީހުން ވިސްނައި ދެނެގަތުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","74","ثُمَّ قَسَتۡ قُلُوبُكُم مِّنۢ بَعۡدِ ذَٰلِكَ فَهِيَ كَٱلۡحِجَارَةِ أَوۡ أَشَدُّ قَسۡوَةٗۚ وَإِنَّ مِنَ ٱلۡحِجَارَةِ لَمَا يَتَفَجَّرُ مِنۡهُ ٱلۡأَنۡهَٰرُۚ وَإِنَّ مِنۡهَا لَمَا يَشَّقَّقُ فَيَخۡرُجُ مِنۡهُ ٱلۡمَآءُۚ وَإِنَّ مِنۡهَا لَمَا يَهۡبِطُ مِنۡ خَشۡيَةِ ٱللَّهِۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا تَعۡمَلُونَ ٧٤","ثم قست قلوبكم من بعد ذلك فهي كالحجارة أو أشد قسوة وإن من الحجارة لما يتفجر منه الأنهار وإن منها لما يشقق فيخرج منه الماء وإن منها لما يهبط من خشية الله وما الله بغافل عما تعملون","ދެން އެއަށްފަހުގައި ތިޔަބައިމީހުންގެ ހިތްތައް ގާވެ ހަރުކަށިވިއެވެ. ފަހެ، އެ ހިތްތައް ހިލައެކޭ އެއްފަދައެވެ. ނުވަތަ އެއަށްވުރެވެސް ހަރުކަން ގަދައެވެ. (އެހެނީ) ހަމަކަށަވަރުން، އެއިން ފެން ކޯރުތައް އުފެދިގެން އަންނަ ހިލަ، ހިލަތަކުގެ ތެރެއިންވެއެވެ. އަދި ހަމަކަށަވަރުން، ފަޅިފަޅިވެގެންގޮސް އެއިން ފެން ނިކުންނަ ހިލަވެސް އޭގެތެރެއިން ވެއެވެ. އަދި ހަމަކަށަވަރުން، ﷲއަށް ބިރުވެތިވުމުގެ ސަބަބުން ތިރިއަށް ފައިބާ ހިލަވެސް އޭގެތެރެއިން ވެއެވެ. ތިޔަބައިމީހުން ކުރާ ޢަމަލު ތަކާމެދު ޣާފިލު ވެވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ނުވެއެވެ.","",""],["₂ سورة البقرة","75","۞أَفَتَطۡمَعُونَ أَن يُؤۡمِنُواْ لَكُمۡ وَقَدۡ كَانَ فَرِيقٞ مِّنۡهُمۡ يَسۡمَعُونَ كَلَٰمَ ٱللَّهِ ثُمَّ يُحَرِّفُونَهُۥ مِنۢ بَعۡدِ مَا عَقَلُوهُ وَهُمۡ يَعۡلَمُونَ ٧٥","أفتطمعون أن يؤمنوا لكم وقد كان فريق منهم يسمعون كلام الله ثم يحرفونه من بعد ما عقلوه وهم يعلمون","ފަހެ، ތިޔަބައިމީހުންނަށް (އެބަހީ: ރަސޫލާ އާއި މުއުމިނުންގެ ގޮވާލުމަށް) އެއުރެން (އިޖާބަދީ) އީމާން ވުމަށް، ތިޔަބައިމީހުން އުންމީދު ކުރަނީ ހެއްޔެވެ؟ ﷲގެ ކަލާމްފުޅު އަހައި، އެއުރެން އެ ކަލާމްފުޅު ވިސްނައި ދެނެގަތުމަށްފަހު، އެއުރެން ދެނެތިބެ، ދެން އެ ކަލާމްފުޅު ބަދަލުކުރާ ބަޔަކު އެއުރެންގެ ތެރެއިން ވާކަން ކަށަވަރެވެ.","",""],["₂ سورة البقرة","76","وَإِذَا لَقُواْ ٱلَّذِينَ ءَامَنُواْ قَالُوٓاْ ءَامَنَّا وَإِذَا خَلَا بَعۡضُهُمۡ إِلَىٰ بَعۡضٖ قَالُوٓاْ أَتُحَدِّثُونَهُم بِمَا فَتَحَ ٱللَّهُ عَلَيۡكُمۡ لِيُحَآجُّوكُم بِهِۦ عِندَ رَبِّكُمۡۚ أَفَلَا تَعۡقِلُونَ ٧٦","وإذا لقوا الذين آمنوا قالوا آمنا وإذا خلا بعضهم إلى بعض قالوا أتحدثونهم بما فتح الله عليكم ليحاجوكم به عند ربكم أفلا تعقلون","އަދި އީމާންވި މީހުންނާ އެއުރެން ބައްދަލުވެއްޖެނަމަ، އެއުރެން ބުނެއުޅެނީ، ތިމަންމެން މިތިބީ އީމާން ވެގެންނެވެ. އަދި އެއުރެންގެ އެއްބަޔަކު އަނެއްބަޔަކާ ބައްދަލުވެ، އެއްތަންވެއްޖެނަމަ، އެއުރެން ބުނެތެވެ. (ތައުރާތުގައި) ﷲ ތިޔަބައިމީހުންނަށް ބަޔާންކޮށްދެއްވައި އަންގަވާފައިވާ އެންގެވުންތަކުގެ ވާހަކަ އެއުރެންނަށް (އެބަހީ: މުސްލިމުންނަށް) ތިޔަބައިމީހުން ކިޔައިދެނީ ހެއްޔެވެ؟ (އޭރުން) ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި އެއިން ތިޔަބައިމީހުންގެ މައްޗަށް އެއުރެން (އެބަހީ: މުސްލިމުން) ހުއްޖަތް ދައްކައިފާނެތެވެ. ފަހެ، ތިޔަބައިމީހުން ނުވިސްނަނީހެއްޔެވެ؟","",""],["₂ سورة البقرة","77","أَوَ لَا يَعۡلَمُونَ أَنَّ ٱللَّهَ يَعۡلَمُ مَا يُسِرُّونَ وَمَا يُعۡلِنُونَ ٧٧","أولا يعلمون أن الله يعلم ما يسرون وما يعلنون","އެއުރެން ސިއްރުކުރާހާ ކަންތަކާއި ފާޅުކުރާހާ ކަންތައް، ﷲ ދެނެވޮޑިގެންވާކަން، އެއުރެން ނުދަންނަނީހެއްޔެވެ؟","",""],["₂ سورة البقرة","78","وَمِنۡهُمۡ أُمِّيُّونَ لَا يَعۡلَمُونَ ٱلۡكِتَٰبَ إِلَّآ أَمَانِيَّ وَإِنۡ هُمۡ إِلَّا يَظُنُّونَ ٧٨","ومنهم أميون لا يعلمون الكتاب إلا أماني وإن هم إلا يظنون","އަދި އެއުރެންގެތެރޭގައި ލިޔާންކިޔާން ނުދަންނަ މީހުންވެސްވެއެވެ. ފޮތުންވެސް، މުސްތަހީލު އުންމީދުތަކެއްނޫނީ އެއުރެންނަކަށް ނުފެނެއެވެ. އަދި ހީތަކެއް ކުރާކަމުގައިނޫނީ، އެއުރެން ނުވެތެވެ.","",""],["₂ سورة البقرة","79","فَوَيۡلٞ لِّلَّذِينَ يَكۡتُبُونَ ٱلۡكِتَٰبَ بِأَيۡدِيهِمۡ ثُمَّ يَقُولُونَ هَٰذَا مِنۡ عِندِ ٱللَّهِ لِيَشۡتَرُواْ بِهِۦ ثَمَنٗا قَلِيلٗاۖ فَوَيۡلٞ لَّهُم مِّمَّا كَتَبَتۡ أَيۡدِيهِمۡ وَوَيۡلٞ لَّهُم مِّمَّا يَكۡسِبُونَ ٧٩","فويل للذين يكتبون الكتاب بأيديهم ثم يقولون هذا من عند الله ليشتروا به ثمنا قليلا فويل لهم مما كتبت أيديهم وويل لهم مما يكسبون","ފަހެ، އެއުރެންގެ އަމިއްލަ އަތުން ފޮތްލިޔެ، މިއީ ﷲގެ ހަޒުރަތުން ބާވައިލެއްވި ފޮތޭ ބުނާ މީހުންނަށް ގެއްލުމާއި ހަލާކުހުށްޓެވެ. (އެއުރެން އެކަންކުރަނީ) ކުޑައަގެއް އެއަށް ގަތުމަށްޓަކައެވެ. ފަހެ، އެއުރެންގެ އަމިއްލަ އަތުން ލިޔުނު ތަކެތީގެ ސަބަބުން، އެއުރެންނަށް ގެއްލުމާއި ހަލާކު ހުށްޓެވެ. އަދި އެއުރެން ހޯދައިގަންނަ ތަކެތިންވެސް، އެއުރެންނަށް ގެއްލުމާއި ހަލާކުހުށްޓެވެ.","",""],["₂ سورة البقرة","80","وَقَالُواْ لَن تَمَسَّنَا ٱلنَّارُ إِلَّآ أَيَّامٗا مَّعۡدُودَةٗۚ قُلۡ أَتَّخَذۡتُمۡ عِندَ ٱللَّهِ عَهۡدٗا فَلَن يُخۡلِفَ ٱللَّهُ عَهۡدَهُۥٓۖ أَمۡ تَقُولُونَ عَلَى ٱللَّهِ مَا لَا تَعۡلَمُونَ ٨٠","وقالوا لن تمسنا النار إلا أياما معدودة قل أتخذتم عند الله عهدا فلن يخلف الله عهده أم تقولون على الله ما لا تعلمون","އަދި އެއުރެން ބުނޫއެވެ. އަދަދުކުރެވިގެންވާ (އެބަހީ: މަދު) ދުވަސްކޮޅެއްގައި މެނުވީ، ނަރަކައިގެ އަލިފާން ތިމަންމެން ގަޔަކު ނުބީހޭނެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ﷲގެ ހަޒުރަތުން (އެކަމަށް) އަހުދެއް ހިފާފައި އޮތީހެއްޔެވެ؟ އެހެންކަމަށްވަނީނަމަ، ﷲ އެކަލާނގެ އަހުދު ފުޅަކާ ޚިލާފު ވެވޮޑިއެއް ނުގަންނަވާނެތެވެ. ނޫންނަމަ، ތިޔަބައިމީހުންނަށް އެނގިގެންނުވާ އެއްޗެއް، ﷲއާމެދު ތިޔަބައިމީހުން ބުނަނީހެއްޔެވެ؟","",""],["₂ سورة البقرة","81","بَلَىٰۚ مَن كَسَبَ سَيِّئَةٗ وَأَحَٰطَتۡ بِهِۦ خَطِيٓـَٔتُهُۥ فَأُوْلَـٰٓئِكَ أَصۡحَٰبُ ٱلنَّارِۖ هُمۡ فِيهَا خَٰلِدُونَ ٨١","بلى من كسب سيئة وأحاطت به خطيئته فأولئك أصحاب النار هم فيها خالدون","އެހެންނަކުންނޫނެވެ. ފާފަކޮށް، އެމީހެއްގެކުށް އެމީހަކު ވަށާލައިފި މީހުންނީ (އެބަހީ: އެއުރެންގެ ކުށްތަކުގެ ތެރެޔަށް ގެނބިގެންފި މީހުންނީ) ނަރަކައިގެ އަހުލުވެރިންނެވެ. އެއުރެންނީ، އެތާނގައި ދެމިތިބޭނޭ މީހުންނެވެ.","",""],["₂ سورة البقرة","82","وَٱلَّذِينَ ءَامَنُواْ وَعَمِلُواْ ٱلصَّـٰلِحَٰتِ أُوْلَـٰٓئِكَ أَصۡحَٰبُ ٱلۡجَنَّةِۖ هُمۡ فِيهَا خَٰلِدُونَ ٨٢","والذين آمنوا وعملوا الصالحات أولئك أصحاب الجنة هم فيها خالدون","އަދި އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަމީހުން، އެއީ ސުވަރުގޭގެ އަހުލުވެރިންނެވެ. އެއުރެންނީ، އެތާނގައި ދެމިތިބޭނޭ މީހުންނެވެ.","",""],["₂ سورة البقرة","83","وَإِذۡ أَخَذۡنَا مِيثَٰقَ بَنِيٓ إِسۡرَـٰٓءِيلَ لَا تَعۡبُدُونَ إِلَّا ٱللَّهَ وَبِٱلۡوَٰلِدَيۡنِ إِحۡسَانٗا وَذِي ٱلۡقُرۡبَىٰ وَٱلۡيَتَٰمَىٰ وَٱلۡمَسَٰكِينِ وَقُولُواْ لِلنَّاسِ حُسۡنٗا وَأَقِيمُواْ ٱلصَّلَوٰةَ وَءَاتُواْ ٱلزَّكَوٰةَ ثُمَّ تَوَلَّيۡتُمۡ إِلَّا قَلِيلٗا مِّنكُمۡ وَأَنتُم مُّعۡرِضُونَ ٨٣","وإذ أخذنا ميثاق بني إسرائيل لا تعبدون إلا الله وبالوالدين إحسانا وذي القربى واليتامى والمساكين وقولوا للناس حسنا وأقيموا الصلاة وآتوا الزكاة ثم توليتم إلا قليلا منكم وأنتم معرضون","އިސްރާއީލުގެ ދަރިންގެ ކިބައިން، ތިމަންރަސްކަލާނގެ ކަށަވަރުވެގެންވާ އަހުދު ހިއްޕެވިހިނދު، ހަނދުމަކުރާށެވެ! އެއީ، ﷲއަށް މެނުވީ ތިޔަބައިމީހުން އަޅުކަން ނުކުޅައުމަށެވެ. އަދި މައިންބަފައިންނާއި، ގާތްތިމާގެ މީހުންނާއި، ޔަތީމްނާއި، މިސްކީނުންނަށް ހެޔޮކޮށް ހިތުމަށެވެ. އަދި ތިޔަބައިމީހުން މީސްތަކުންނަށް ހެޔޮބަސްބުނާށެވެ! އަދި ތިޔަބައިމީހުން ނަމާދު ގާއިމުކުރާށެވެ! އަދި ޒަކާތް ދޭށެވެ! ދެން ތިޔަބައިމީހުން ދެކޮޅުވެރިވެގެންވާ ޙާލު، ތިޔަބައިމީހުންގެ ތެރެއިން މަދު ބަޔަކު މެނުވީ (އަހުދު ފުއްދުމަށް) ފުރަގަސްދިނީއެވެ.","",""],["₂ سورة البقرة","84","وَإِذۡ أَخَذۡنَا مِيثَٰقَكُمۡ لَا تَسۡفِكُونَ دِمَآءَكُمۡ وَلَا تُخۡرِجُونَ أَنفُسَكُم مِّن دِيَٰرِكُمۡ ثُمَّ أَقۡرَرۡتُمۡ وَأَنتُمۡ تَشۡهَدُونَ ٨٤","وإذ أخذنا ميثاقكم لا تسفكون دماءكم ولا تخرجون أنفسكم من دياركم ثم أقررتم وأنتم تشهدون","އަދި ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންގެ ކިބައިން ކަށަވަރުވެގެންވާ އަހުދު ހިއްޕެވިހިނދު ހަނދުމަކުރާށެވެ! އެއީ، ތިޔަބައިމީހުންގެ ލޭ ތިޔަބައިމީހުން ނުއޮހޮރުވުމަށެވެ. އަދި ތިޔަބައިމީހުންގެ ގޯތިގެދޮރުން ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތައް ނުނެރުމަށެވެ. ދެން ތިޔަބައިމީހުން (އެކަމަށް) ހެކިވެ ތިބޭ ޙާލު (އެ އަހުދަށް) އެއްބަސްވެ އިގްރާރު ވީމުއެވެ.","",""],["₂ سورة البقرة","85","ثُمَّ أَنتُمۡ هَـٰٓؤُلَآءِ تَقۡتُلُونَ أَنفُسَكُمۡ وَتُخۡرِجُونَ فَرِيقٗا مِّنكُم مِّن دِيَٰرِهِمۡ تَظَٰهَرُونَ عَلَيۡهِم بِٱلۡإِثۡمِ وَٱلۡعُدۡوَٰنِ وَإِن يَأۡتُوكُمۡ أُسَٰرَىٰ تُفَٰدُوهُمۡ وَهُوَ مُحَرَّمٌ عَلَيۡكُمۡ إِخۡرَاجُهُمۡۚ أَفَتُؤۡمِنُونَ بِبَعۡضِ ٱلۡكِتَٰبِ وَتَكۡفُرُونَ بِبَعۡضٖۚ فَمَا جَزَآءُ مَن يَفۡعَلُ ذَٰلِكَ مِنكُمۡ إِلَّا خِزۡيٞ فِي ٱلۡحَيَوٰةِ ٱلدُّنۡيَاۖ وَيَوۡمَ ٱلۡقِيَٰمَةِ يُرَدُّونَ إِلَىٰٓ أَشَدِّ ٱلۡعَذَابِۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا تَعۡمَلُونَ ٨٥","ثم أنتم هؤلاء تقتلون أنفسكم وتخرجون فريقا منكم من ديارهم تظاهرون عليهم بالإثم والعدوان وإن يأتوكم أسارى تفادوهم وهو محرم عليكم إخراجهم أفتؤمنون ببعض الكتاب وتكفرون ببعض فما جزاء من يفعل ذلك منكم إلا خزي في الحياة الدنيا ويوم القيامة يردون إلى أشد العذاب وما الله بغافل عما تعملون","ދެން ހަމަ ތިޔަބައިމީހުން، ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތައް މަރައި، އަދި ތިޔަބައިމީހުންގެ ބަޔަކު، އެއުރެންގެ ގޯތިގެދޮރުން ނެރެލައި ތިޔަހަދަނީއެވެ. އެއީ، ފާފަވެރިކަމާއި އަދާވަތް ތެރިކަމުގެ ގޮތުން އެއުރެންގެ މައްޗަށް ތިޔަބައިމީހުން އެއްބަޔަކު އަނެއްބަޔަކާ ވާގިވެރިވެ، އެހީތެރިވާ ޙާލު ގައެވެ. އަދި އެއުރެންގެ ތެރެއިން ހައްޔަރުވެވޭ މީހުން ތިޔަބައިމީހުންގެ ގާތަށް އަތުވެއްޖެނަމަ، ތިޔަބައިމީހުން އެއުރެންގެ ފިދުޔަ ދީ، އެއުރެން ސަލާމަތްކުރެތެވެ. އަދި (އެއުރެންގެ ގޯތިގެދޮރުން) އެއުރެން ނެރެލުމީ، ތިޔަބައިމީހުންގެ މައްޗަށް ހަރާމް ވެގެންވާ ކަމެކެވެ. ފަހެ، ފޮތުން ބަޔަކަށް ތިޔަބައިމީހުން އީމާންވެ، އަނެއްބަޔަށް ކާފިރު ވަނީ ހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުންގެ ތެރެއިން އެކަންތައްކުރާ މީހުންގެ ޖަޒާއަކީ، ދުނިޔޭގެ ހަޔާތުގައި ދެރަކަމާއި ނިކަމެތިކަން ލިބުންކަމުގައި މެނުވީ ނުވެއެވެ. އަދި ގިޔާމަތް ދުވަހުން ގަދަފަދަ އަޒާބުގެ ތެރެޔަށް އެއުރެން ފޮނުއްވާހުށްޓެވެ. އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުންކުރާ ޢަމަލު ތަކާމެދު ޣާފިލު ވެވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ނުވެއެވެ.","",""],["₂ سورة البقرة","86","أُوْلَـٰٓئِكَ ٱلَّذِينَ ٱشۡتَرَوُاْ ٱلۡحَيَوٰةَ ٱلدُّنۡيَا بِٱلۡأٓخِرَةِۖ فَلَا يُخَفَّفُ عَنۡهُمُ ٱلۡعَذَابُ وَلَا هُمۡ يُنصَرُونَ ٨٦","أولئك الذين اشتروا الحياة الدنيا بالآخرة فلا يخفف عنهم العذاب ولا هم ينصرون","އަހުރެންނީ، އާޚިރަތްގެ ބާއްޖަވެރިކަމުގެ ބަދަލުގައި، ދުނިޔޭގެ ދިރިއުޅުން ހޯދައިގަތް މީހުންނެވެ. ފަހެ، އެއުރެންގެ ކިބަޔަކުން އަޒާބެއް ލުޔެއް ނުކުރައްވާހުށްޓެވެ. އަދި ނަސްރު ލިބޭނޭ ބަޔަކު ކަމުގައިވެސް، އެއުރެން ނުވެތެވެ.","",""],["₂ سورة البقرة","87","وَلَقَدۡ ءَاتَيۡنَا مُوسَى ٱلۡكِتَٰبَ وَقَفَّيۡنَا مِنۢ بَعۡدِهِۦ بِٱلرُّسُلِۖ وَءَاتَيۡنَا عِيسَى ٱبۡنَ مَرۡيَمَ ٱلۡبَيِّنَٰتِ وَأَيَّدۡنَٰهُ بِرُوحِ ٱلۡقُدُسِۗ أَفَكُلَّمَا جَآءَكُمۡ رَسُولُۢ بِمَا لَا تَهۡوَىٰٓ أَنفُسُكُمُ ٱسۡتَكۡبَرۡتُمۡ فَفَرِيقٗا كَذَّبۡتُمۡ وَفَرِيقٗا تَقۡتُلُونَ ٨٧","ولقد آتينا موسى الكتاب وقفينا من بعده بالرسل وآتينا عيسى ابن مريم البينات وأيدناه بروح القدس أفكلما جاءكم رسول بما لا تهوى أنفسكم استكبرتم ففريقا كذبتم وفريقا تقتلون","ހަމަކަށަވަރުން، ތިމަންރަސްލާނގެ މޫސާގެފާނަށް ފޮތް (އެބަހީ: ތައުރާތު) ދެއްވީމެވެ. އަދި އެކަލޭގެފާނަށް ފަހުގައި ވިދިވިދިގެން ރަސޫލު ބޭކަލުން ފޮނުއްވީމެވެ. އަދި މަރިޔަމްގެފާނުގެ ދަރިކަލުން ޢީސާގެފާނަށް ތިމަންރަސްކަލާނގެ ފާޅުވެގެންވާ މުއުޖުޒާތްތައް ދެއްވީމެވެ. އަދި ރޫޙުލް ގުދުސްގެ އެހީފުޅުން އެކަލޭގެފާނަށް ގަދަކަން ދެއްވީމެވެ. ފަހެ، ތިޔަބައިމީހުންގެ ނަފްސުތައް ނޭދޭ ކަމަކާއިގެން ތިޔަބައިމީހުންގެ ގާތަށް ރަސޫލަކު ވަޑައިގެންފި ކޮންމެ ހިނދެއްގައި (އެކަމަށް އިޖާބަނުދީ) ތިޔަބައިމީހުން ބޮޑާވެގަންނަނީ ހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުން އޭގެ ބަޔެއް ރަސޫލުން ދޮގުކުޅައީމުއެވެ. އަނެއްބައި ރަސޫލުން ގަތުލުކުޅައީމުއެވެ.","",""],["₂ سورة البقرة","88","وَقَالُواْ قُلُوبُنَا غُلۡفُۢۚ بَل لَّعَنَهُمُ ٱللَّهُ بِكُفۡرِهِمۡ فَقَلِيلٗا مَّا يُؤۡمِنُونَ ٨٨","وقالوا قلوبنا غلف بل لعنهم الله بكفرهم فقليلا ما يؤمنون","އެއުރެން ބުނީ ތިމަންމެންގެ ހިތްތައްވަނީ އުރައެއްލެވި ބަންދުވެފައެވެ. އެހެނެއްނޫނެވެ. އެއުރެންގެ ކާފިރުކަމުގެ ސަބަބުން، ﷲއެއުރެންނަށް ލައުނަތް ލެއްވީއެވެ. ފަހެ، އެއުރެން އީމާން ވަނީ ވަރަށްވެސް ކުޑަކޮށެވެ.","",""],["₂ سورة البقرة","89","وَلَمَّا جَآءَهُمۡ كِتَٰبٞ مِّنۡ عِندِ ٱللَّهِ مُصَدِّقٞ لِّمَا مَعَهُمۡ وَكَانُواْ مِن قَبۡلُ يَسۡتَفۡتِحُونَ عَلَى ٱلَّذِينَ كَفَرُواْ فَلَمَّا جَآءَهُم مَّا عَرَفُواْ كَفَرُواْ بِهِۦۚ فَلَعۡنَةُ ٱللَّهِ عَلَى ٱلۡكَٰفِرِينَ ٨٩","ولما جاءهم كتاب من عند الله مصدق لما معهم وكانوا من قبل يستفتحون على الذين كفروا فلما جاءهم ما عرفوا كفروا به فلعنة الله على الكافرين","އަދި އެއުރެންނާ އެކުގައިވާ ފޮތްތައް (އެބަހީ: ތައުރާތާއި އިންޖީލު) ގަބޫލުކޮށް ތެދުކުރާގޮތުގައި ﷲގެ ހަޒުރަތުން އެއުރެންނާހަމަޔަށް ފޮތެއް (އެބަހީ: ގުރްއާން) އައިހިނދު (އެފޮތް އެއުރެން ދޮގުކުރޫއެވެ.) އޭގެ ކުރިން، އެއުރެން، ކާފިރު ވެގަތް މީސްތަކުންގެ މައްޗަށް ނަސްރު އެދޭކަމުގައި ވޫއެވެ. ދެން އެއުރެންނަށް އެނގިފައިވާ ހައްގު ގޮތް އެއުރެންނާހަމަޔަށް އައިހިނދު އެއަށް އެއުރެން ކާފިރު ވޫއެވެ. ފަހެ، ކާފިރުންގެ މައްޗަށް ﷲގެ ލައުނަތް ހުށްޓެވެ.","",""],["₂ سورة البقرة","90","بِئۡسَمَا ٱشۡتَرَوۡاْ بِهِۦٓ أَنفُسَهُمۡ أَن يَكۡفُرُواْ بِمَآ أَنزَلَ ٱللَّهُ بَغۡيًا أَن يُنَزِّلَ ٱللَّهُ مِن فَضۡلِهِۦ عَلَىٰ مَن يَشَآءُ مِنۡ عِبَادِهِۦۖ فَبَآءُو بِغَضَبٍ عَلَىٰ غَضَبٖۚ وَلِلۡكَٰفِرِينَ عَذَابٞ مُّهِينٞ ٩٠","بئسما اشتروا به أنفسهم أن يكفروا بما أنزل الله بغيا أن ينزل الله من فضله على من يشاء من عباده فباءوا بغضب على غضب وللكافرين عذاب مهين","އެއުރެންގެ ނަފްސުތައް އެކަމަކަށް ވިއްކައިލި ކަމެއްގެ ނުބައިކަން ބޮޑުކަމާއެވެ! އެއީ، ﷲ ބާވައިލެއްވި ތަކެއްޗަށް (އެބަހީ: ގުރްއާނަށް) އެއުރެން ކާފިރު ވުމެވެ. (އެއުރެން އެ ކާފިރު ވީ) ﷲގެ ފަޟްލު ވަންތަކަމުން އެކަލާނގެ އަޅުތަކުންގެ ތެރެއިން އެކަލާނގެ އިރާދަކުރެއްވި ބަޔަކުގެ މައްޗަށް ބާވައިލެއްވި ބާވައިލެއްވުމަށް ހަސަދަވެރިވުމުގެ ގޮތުންނެވެ. ދެން ކޯފާގެ މައްޗަށް ކޯފާ އާއިގެން އެއުރެން އެނބުރި އަތުވެއްޖައޫއެވެ. އަދި ކާފިރުންނަށް ހުރީ އިހާނަތްތެރިކަން ދެނިވި އަޒާބެވެ.","",""],["₂ سورة البقرة","91","وَإِذَا قِيلَ لَهُمۡ ءَامِنُواْ بِمَآ أَنزَلَ ٱللَّهُ قَالُواْ نُؤۡمِنُ بِمَآ أُنزِلَ عَلَيۡنَا وَيَكۡفُرُونَ بِمَا وَرَآءَهُۥ وَهُوَ ٱلۡحَقُّ مُصَدِّقٗا لِّمَا مَعَهُمۡۗ قُلۡ فَلِمَ تَقۡتُلُونَ أَنۢبِيَآءَ ٱللَّهِ مِن قَبۡلُ إِن كُنتُم مُّؤۡمِنِينَ ٩١","وإذا قيل لهم آمنوا بما أنزل الله قالوا نؤمن بما أنزل علينا ويكفرون بما وراءه وهو الحق مصدقا لما معهم قل فلم تقتلون أنبياء الله من قبل إن كنتم مؤمنين","އަދި ﷲ ބާވައިލެއްވި ފޮތަށް (އެބަހީ: ގުރްއާނަށް) ތިޔަބައިމީހުން އީމާން ވާށޭ އެއުރެންގެ ގާތުގައި ބުނެފިނަމަ، އެއުރެން ބުނެތެވެ. ތިމަންމެން އީމާން ވާނީ، ތިމަންމެންގެ މައްޗަށް ބާވައިލެއްވި ފޮތަށެވެ. އޭގެފަހުން ބާވައިލެއްވި ފޮތަށް (އެބަހީ: ގުރްއާނަށް) އެއުރެން ކާފިރު ވަނީ، އެއުރެންނާ އެކުގައިވާފޮތް (އެބަހީ: ތައުރާތު) ތެދުކުރާ ހައްގު ފޮތްކަމުގައި، އެ ގުރްއާންވާ ޙާލު ގައެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން މުއުމިނުން ކަމުގައިވަނީނަމަ، މީގެކުރީގައި ތިޔަބައިމީހުން ﷲގެ ނަބިއްޔުން ގަތުލު ކޮށް އުޅުނީ ފަހެ، ކީއްވެގެންހެއްޔެވެ؟","",""],["₂ سورة البقرة","92","۞وَلَقَدۡ جَآءَكُم مُّوسَىٰ بِٱلۡبَيِّنَٰتِ ثُمَّ ٱتَّخَذۡتُمُ ٱلۡعِجۡلَ مِنۢ بَعۡدِهِۦ وَأَنتُمۡ ظَٰلِمُونَ ٩٢","ولقد جاءكم موسى بالبينات ثم اتخذتم العجل من بعده وأنتم ظالمون","އަދި ހަމަކަށަވަރުން، ބަޔާންވެގެންވާ މުއުޖުޒާތް ތަކާއިގެން މޫސާގެފާނު ތިޔަބައިމީހުންގެގާތަށް ވަޑައިގަތެވެ. ދެން އެކަލޭގެފާނު ދުރަށްވަޑައިގަތުމަށްފަހު، ތިޔަބައިމީހުން، ގެރިއަކީ އިލާހަކު ކަމުގައި ބަލައިގެން އުޅުނީމުއެވެ. (އެއީ) އަނިޔާވެރި ބަޔަކުކަމުގައި ތިޔަބައިމީހުންވާ ޙާލު ގައެވެ.","",""],["₂ سورة البقرة","93","وَإِذۡ أَخَذۡنَا مِيثَٰقَكُمۡ وَرَفَعۡنَا فَوۡقَكُمُ ٱلطُّورَ خُذُواْ مَآ ءَاتَيۡنَٰكُم بِقُوَّةٖ وَٱسۡمَعُواْۖ قَالُواْ سَمِعۡنَا وَعَصَيۡنَا وَأُشۡرِبُواْ فِي قُلُوبِهِمُ ٱلۡعِجۡلَ بِكُفۡرِهِمۡۚ قُلۡ بِئۡسَمَا يَأۡمُرُكُم بِهِۦٓ إِيمَٰنُكُمۡ إِن كُنتُم مُّؤۡمِنِينَ ٩٣","وإذ أخذنا ميثاقكم ورفعنا فوقكم الطور خذوا ما آتيناكم بقوة واسمعوا قالوا سمعنا وعصينا وأشربوا في قلوبهم العجل بكفرهم قل بئسما يأمركم به إيمانكم إن كنتم مؤمنين","އަދި ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންގެ ކިބައިން ކަށަވަރުވެގެންވާ އަހުދު ހިއްޕަވައި، އަދި ތިޔަބައިމީހުންގެ މައްޗަށް ޠޫރު ފަރުބަދަ އުފުއްލެވިހިނދު ހަނދުމަކުރާށެވެ! (އެހިނދު ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް އެންގެވީމެވެ.) ތިޔަބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ ދެއްވި އެއްޗެއްގައި، (އެބަހީ: ފޮތުގައި) ތިޔަބައިމީހުން ގަދަޔަށް ހިފަހައްޓާށެވެ! އަދި (ތިޔަބައިމީހުންނަށް ކުރެވޭ އަމުރުތައް) ތިޔަބައިމީހުން އަހާށެވެ! އެއުރެން ދެންނެވޫއެވެ. ތިމަންމެން (ތިޔަ ބަސްފުޅު) އަހައި (ތިޔަ އަމުރު ފުޅަށް) ނުކިޔަމަންތެރިވެ އުރެދިއްޖައީމުއެވެ. އަދި އެއުރެންގެ ކާފިރުކަމުގެ ސަބަބުން، ގެރިއަށް އަޅުކަންކުރުމުގެ ލޯބި އެއުރެންގެ ހިތްތަކުގައިވަނީ ވަރުގަދައަކަށް ހިފައިފައެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! (ތިޔަބުނާހެން) ތިޔަބައިމީހުންނީ، އީމާންވާ ބަޔަކުކަމުގައި ވަނީނަމަ، ތިޔަބައިމީހުންގެ އީމާން ކަން، އެކަމަކަށް ތިޔަބައިމީހުންނަށް އަމުރުކުރާ ކަމެއްގެ ނުބައިކަން ބޮޑުކަމާއެވެ!","",""],["₂ سورة البقرة","94","قُلۡ إِن كَانَتۡ لَكُمُ ٱلدَّارُ ٱلۡأٓخِرَةُ عِندَ ٱللَّهِ خَالِصَةٗ مِّن دُونِ ٱلنَّاسِ فَتَمَنَّوُاْ ٱلۡمَوۡتَ إِن كُنتُمۡ صَٰدِقِينَ ٩٤","قل إن كانت لكم الدار الآخرة عند الله خالصة من دون الناس فتمنوا الموت إن كنتم صادقين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲގެ ހަޒުރަތުގައި، އާޚިރަތްގެ ގޮވަތި އެހެނިހެން މީސްތަކުން ފިޔަވައި ތިޔަބައިމީހުންނަށް ހާއްސަކުރައްވާފައިވާނަމަ، ތިޔަބައިމީހުން، ނިކަން މަރުވުން އެދިބަލާށެވެ! (އެއީ) ތިޔަބައިމީހުންނީ، ތެދުވެރިން ކަމުގައި ވަނީނަމައެވެ.","",""],["₂ سورة البقرة","95","وَلَن يَتَمَنَّوۡهُ أَبَدَۢا بِمَا قَدَّمَتۡ أَيۡدِيهِمۡۚ وَٱللَّهُ عَلِيمُۢ بِٱلظَّـٰلِمِينَ ٩٥","ولن يتمنوه أبدا بما قدمت أيديهم والله عليم بالظالمين","ދުވަހަކުވެސް އެއުރެން އެ މަރަކަށް ނޭދޭނެތެވެ. އެއީ، އެއުރެންގެ އަތްތައް އިސްކޮށްފައިވާ ނުބައި ޢަމަލުތަކުގެ ސަބަބުންނެވެ. ﷲއީ، އަނިޔާވެރިން މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","96","وَلَتَجِدَنَّهُمۡ أَحۡرَصَ ٱلنَّاسِ عَلَىٰ حَيَوٰةٖ وَمِنَ ٱلَّذِينَ أَشۡرَكُواْۚ يَوَدُّ أَحَدُهُمۡ لَوۡ يُعَمَّرُ أَلۡفَ سَنَةٖ وَمَا هُوَ بِمُزَحۡزِحِهِۦ مِنَ ٱلۡعَذَابِ أَن يُعَمَّرَۗ وَٱللَّهُ بَصِيرُۢ بِمَا يَعۡمَلُونَ ٩٦","ولتجدنهم أحرص الناس على حياة ومن الذين أشركوا يود أحدهم لو يعمر ألف سنة وما هو بمزحزحه من العذاب أن يعمر والله بصير بما يعملون","އަދި މީސްތަކުންކުރެ ދުނިޔޭގެ ދިރިއުޅުމަށް އެންމެ ދަހިވެތިކަން ބޮޑު، އަދި ޝަރީކުކުޅަ މީހުންނަށްވުރެވެސް (ދިރިއުޅުމަށް ދަހިވެތިކަން ބޮޑު) ބަޔަކު ކަމުގައި ކަލޭގެފާނަށް އެއުރެން ފެނިވަޑައިގަންނަވާނެކަން ކަށަވަރެވެ. އެއުރެންކުރެ ކޮންމެ މީހަކުމެ، އެއްހާސް އަހަރަށް އުމުރު ދިގުވާނެނަމައޭ ހީކޮށް، އެކަމަށް އެދޭނެތެވެ. އެ އުމުރު ދިގުވުން އެއީ، އެމީހަކު އަޒާބުން ދުރުކުރަނިވި ކަމެއްކަމުގައި ނުމެވޭމެއެވެ. ﷲއީ އެއުރެންކުރާ ކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","97","قُلۡ مَن كَانَ عَدُوّٗا لِّـجِبۡرِيلَ فَإِنَّهُۥ نَزَّلَهُۥ عَلَىٰ قَلۡبِكَ بِإِذۡنِ ٱللَّهِ مُصَدِّقٗا لِّمَا بَيۡنَ يَدَيۡهِ وَهُدٗى وَبُشۡرَىٰ لِلۡمُؤۡمِنِينَ ٩٧","قل من كان عدوا لجبريل فإنه نزله على قلبك بإذن الله مصدقا لما بين يديه وهدى وبشرى للمؤمنين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ޖިބްރީލުގެފާނަށް އަދާވަތް ތެރިޔަކު ކަމުގައިވާ މީހަކީ، (ﷲއަށް އަދާވަތް ތެރިޔަކު ކަމުގައިވާ މީހެކެވެ.) އެހެނީ އެކަލޭގެފާނުން، ކަލޭގެފާނުގެ ހިތްޕުޅުގެ މައްޗަށް އެ ގުރްއާންގެނެސްދެއްވީ، ﷲގެ އިޒުނަ ފުޅަށެވެ. އޭގެ ކުރިން ބާވައިލެއްވި ފޮތްތައް ތެދުކުރާ ޙާލު ގައެވެ. މުއުމިނު ތަކުންނަށް ތެދުމަގެއް ކަމުގައްޔާއި، އުފާވެރި ޚަބަރެއް ކަމުގައެވެ.","",""],["₂ سورة البقرة","98","مَن كَانَ عَدُوّٗا لِّلَّهِ وَمَلَـٰٓئِكَتِهِۦ وَرُسُلِهِۦ وَجِبۡرِيلَ وَمِيكَىٰلَ فَإِنَّ ٱللَّهَ عَدُوّٞ لِّلۡكَٰفِرِينَ ٩٨","من كان عدوا لله وملائكته ورسله وجبريل وميكال فإن الله عدو للكافرين","ﷲއާއި އެކަލާނގެ މަލާއިކަތްނާއި، އެކަލާނގެ ރަސޫލުންނާއި، ޖިބްރީލުގެފާނާއި، މީކާއީލްގެފާނަށް އަދާވަތް ތެރިޔަކު ކަމުގައިވާ މީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ކާފިރުންނަށް އަދާވަތް ތެރިވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","99","وَلَقَدۡ أَنزَلۡنَآ إِلَيۡكَ ءَايَٰتِۭ بَيِّنَٰتٖۖ وَمَا يَكۡفُرُ بِهَآ إِلَّا ٱلۡفَٰسِقُونَ ٩٩","ولقد أنزلنا إليك آيات بينات وما يكفر بها إلا الفاسقون","ހަމަކަށަވަރުން ތިމަންރަސްކަލާނގެ ފާޅުވެ ބަޔާން ވެގެންވާ އާޔަތް ތަކެއް، ކަލޭގެފާނަށް ބާވައިލެއްވީމެވެ. ފާސިގުންނޫން ބަޔަކު އެޔަކަށް ކާފިރެއް ނުވާނެތެވެ.","",""],["₂ سورة البقرة","100","أَوَ كُلَّمَا عَٰهَدُواْ عَهۡدٗا نَّبَذَهُۥ فَرِيقٞ مِّنۡهُمۚ بَلۡ أَكۡثَرُهُمۡ لَا يُؤۡمِنُونَ ١٠٠","أوكلما عاهدوا عهدا نبذه فريق منهم بل أكثرهم لا يؤمنون","އެއުރެން އަހުދެއް ކުރާ ކޮންމެހިނދަކު، އޭގެތެރެއިން ބަޔަކު އެ އަހުދެއްލައިލަނީ ހެއްޔެވެ؟ އަދި ކިއެއްތަ؟ އޭގެ ގިނަމީހުން އީމާނެއް ނުވެތެވެ.","",""],["₂ سورة البقرة","101","وَلَمَّا جَآءَهُمۡ رَسُولٞ مِّنۡ عِندِ ٱللَّهِ مُصَدِّقٞ لِّمَا مَعَهُمۡ نَبَذَ فَرِيقٞ مِّنَ ٱلَّذِينَ أُوتُواْ ٱلۡكِتَٰبَ كِتَٰبَ ٱللَّهِ وَرَآءَ ظُهُورِهِمۡ كَأَنَّهُمۡ لَا يَعۡلَمُونَ ١٠١","ولما جاءهم رسول من عند الله مصدق لما معهم نبذ فريق من الذين أوتوا الكتاب كتاب الله وراء ظهورهم كأنهم لا يعلمون","އަދި އެއުރެންނާއެކުގައިވާ ފޮތް ތެދުކުރައްވާ ރަސޫލަކު، ﷲގެ ހަޒުރަތުން އެއުރެންގެ ގާތަށް ވަޑައިގަތްހިނދު، ފޮތް ލިބުނު މީހުންގެ ތެރެއިން ބަޔަކު، ﷲގެ ފޮތް އެއުރެންގެ ފުރަގަހަށް އެއްލައިލިއެވެ. (އެއީ، ﷲ ބާވައިލެއްވި ފޮތެއްކަންވެސް) އެއުރެން ނުދަންނަ ކަހަލައެވެ.","",""],["₂ سورة البقرة","102","وَٱتَّبَعُواْ مَا تَتۡلُواْ ٱلشَّيَٰطِينُ عَلَىٰ مُلۡكِ سُلَيۡمَٰنَۖ وَمَا كَفَرَ سُلَيۡمَٰنُ وَلَٰكِنَّ ٱلشَّيَٰطِينَ كَفَرُواْ يُعَلِّمُونَ ٱلنَّاسَ ٱلسِّحۡرَ وَمَآ أُنزِلَ عَلَى ٱلۡمَلَكَيۡنِ بِبَابِلَ هَٰرُوتَ وَمَٰرُوتَۚ وَمَا يُعَلِّمَانِ مِنۡ أَحَدٍ حَتَّىٰ يَقُولَآ إِنَّمَا نَحۡنُ فِتۡنَةٞ فَلَا تَكۡفُرۡۖ فَيَتَعَلَّمُونَ مِنۡهُمَا مَا يُفَرِّقُونَ بِهِۦ بَيۡنَ ٱلۡمَرۡءِ وَزَوۡجِهِۦۚ وَمَا هُم بِضَآرِّينَ بِهِۦ مِنۡ أَحَدٍ إِلَّا بِإِذۡنِ ٱللَّهِۚ وَيَتَعَلَّمُونَ مَا يَضُرُّهُمۡ وَلَا يَنفَعُهُمۡۚ وَلَقَدۡ عَلِمُواْ لَمَنِ ٱشۡتَرَىٰهُ مَا لَهُۥ فِي ٱلۡأٓخِرَةِ مِنۡ خَلَٰقٖۚ وَلَبِئۡسَ مَا شَرَوۡاْ بِهِۦٓ أَنفُسَهُمۡۚ لَوۡ كَانُواْ يَعۡلَمُونَ ١٠٢","واتبعوا ما تتلو الشياطين على ملك سليمان وما كفر سليمان ولكن الشياطين كفروا يعلمون الناس السحر وما أنزل على الملكين ببابل هاروت وماروت وما يعلمان من أحد حتى يقولا إنما نحن فتنة فلا تكفر فيتعلمون منهما ما يفرقون به بين المرء وزوجه وما هم بضارين به من أحد إلا بإذن الله ويتعلمون ما يضرهم ولا ينفعهم ولقد علموا لمن اشتراه ما له في الآخرة من خلاق ولبئس ما شروا به أنفسهم لو كانوا يعلمون","އަދި ސުލައިމާނުގެފާނުގެ ވެރިކަމުގެ ޒަމާނުގައި ޝައިތާނު ންތައް ކިޔަވައި އުޅުނު ތަކެއްޗަށް އެއުރެން ތަބާ ވޫއެވެ. ސުލައިމާނުގެފާނު ކާފިރު ވެވަޑައެއް ނުގަނެއެވެ. އެހެނެއްކަމަކު، އެ ޝައިތާނުން ކާފިރު ވޫއެވެ. އެއުރެން މީސްތަކުންނަށް ސިހުރު އުނގަންނައި ދިނުމުންނެވެ. އަދި ބާބިލު ގައިވާ ހާރޫތާއި، މާރޫތާއި ދެ މަލާއިކަތުންގެ މައްޗަށް ބާވައިލެއްވި ތަކެއްޗާވެސް (އެއުރެން ތަބާ ވޫއެވެ.) ތިމަންމެން ވާކަން ކަށަވަރީ (އީމާން ކަންހުރި މިންވަރެއް ބެއްލެވުމުގެ ގޮތުން މެދުވެރި ކުރައްވާފައިވާ) އިމްތިހާނެއް ކަމުގައޭ، ފަހެ (އެ ދަސްކޮށްގެން) ކާފިރު ނުވާށޭ ވިދާޅުވެ (ނަސޭހަތް ދެއްވުމަށް ފަހުގައި) މެނުވީ، އެއްވެސް މީހަކަށް އެ ދެ މަލާއިކަތުން އުނގަންނަވައެއް ނުދެއްވަތެވެ. ފަހެ، މީހާޔާއި އެމީހާގެ އަނބިމީހާޔާ ދެމެދު ދުރުކޮށް ވަކިކުރާނޭގޮތް އެ ދެ މަލާއިކަތުންގެ ކިބައިން އެއުރެން އުނގެނި އުޅެތެވެ. ﷲގެ އިޒުނަ ފުޅާލައިގެން މެނުވީ، އެއްވެސް މީހަކަށް އެއިން ގެއްލުމެއް ދެނިވި ބަޔަކު ކަމުގައި އެއުރެން ނުވެތެވެ. އެއުރެން އެ އުނގެނެނީ އެއުރެންނަށް ގެއްލުންދޭ، އަދި އެއުރެންނަށް މަންފާއެއް ނުކުރާ ކަންތަކެވެ. ހަމަކަށަވަރުން، އެތަކެތި ގަތް މީހަކަށް އާޚިރަތުގައި އެއްވެސް ނަސީބެއް ނެތްކަން، އެއުރެންނަށް ކަށަވަރުކޮށް އެނގިފައިވެއެވެ. އެއުރެންގެ ނަފްސުތައް އެ އެއްޗަކަށް އެ ވިއްކައިލި އެއްޗެއްގެ ނުބައިކަން ބޮޑުކަމާއެވެ! އެއުރެން އެކަން ދަންނަ ކަމުގައި ވިނަމައެވެ.","",""],["₂ سورة البقرة","103","وَلَوۡ أَنَّهُمۡ ءَامَنُواْ وَٱتَّقَوۡاْ لَمَثُوبَةٞ مِّنۡ عِندِ ٱللَّهِ خَيۡرٞۚ لَّوۡ كَانُواْ يَعۡلَمُونَ ١٠٣","ولو أنهم آمنوا واتقوا لمثوبة من عند الله خير لو كانوا يعلمون","ހަމަކަށަވަރުން، އެއުރެން އީމާންވެ ތަގުވާވެރިވިނަމަ، ﷲގެ ހަޒުރަތުން (އެއުރެންނަށް) ހުރި ސަވާބުގެ ހެޔޮކަން މާބޮޑެވެ. އެއުރެން އެކަން ދަންނަ ކަމުގައިވި ނަމައެވެ.","",""],["₂ سورة البقرة","104","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تَقُولُواْ رَٰعِنَا وَقُولُواْ ٱنظُرۡنَا وَٱسۡمَعُواْۗ وَلِلۡكَٰفِرِينَ عَذَابٌ أَلِيمٞ ١٠٤","يا أيها الذين آمنوا لا تقولوا راعنا وقولوا انظرنا واسمعوا وللكافرين عذاب أليم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން (ރަސޫލާގެ އަރިހުގައި) ރާޢިނާ އޭ ނުދަންނަވާށެވެ! އަދި (އޭގެ ބަދަލުގައި) އުންޡުރްނާ އޭ ދަންނަވާށެވެ! އަދި ތިޔަބައިމީހުން (އެކަލޭގެފާނުގެ ބަސްފުޅު ރަނގަޅަށް) އަޑުއަހާށެވެ! އަދި ކާފިރުންނަށް ހުރީ، ވޭންދެނިވި އަޒާބެވެ.","",""],["₂ سورة البقرة","105","مَّا يَوَدُّ ٱلَّذِينَ كَفَرُواْ مِنۡ أَهۡلِ ٱلۡكِتَٰبِ وَلَا ٱلۡمُشۡرِكِينَ أَن يُنَزَّلَ عَلَيۡكُم مِّنۡ خَيۡرٖ مِّن رَّبِّكُمۡۚ وَٱللَّهُ يَخۡتَصُّ بِرَحۡمَتِهِۦ مَن يَشَآءُۚ وَٱللَّهُ ذُو ٱلۡفَضۡلِ ٱلۡعَظِيمِ ١٠٥","ما يود الذين كفروا من أهل الكتاب ولا المشركين أن ينزل عليكم من خير من ربكم والله يختص برحمته من يشاء والله ذو الفضل العظيم","ފޮތުގެ އަހުލުވެރިންގެ ތެރެއިން ވިޔަސް، އަދި މުޝްރިކުންގެ ތެރެއިންވިޔަސް، ކާފިރު ވެއްޖެ މީސްތަކުން ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ތިޔަބައިމީހުންގެ މައްޗަށް އެއްވެސް ހެވެއް ބާވައިލެއްވުމަކަށް ނޭދެތެވެ. (އެކަމަކު) ﷲގެ ރަހުމަތް އެކަލާނގެ އިރާދަކުރެއްވި މީހަކަށް ހާއްސަކުރައްވަތެވެ. ﷲއީ، ބޮޑުވެގެންވާ ފަޟްލު ވަންތަކަމުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","106","۞مَا نَنسَخۡ مِنۡ ءَايَةٍ أَوۡ نُنسِهَا نَأۡتِ بِخَيۡرٖ مِّنۡهَآ أَوۡ مِثۡلِهَآۗ أَلَمۡ تَعۡلَمۡ أَنَّ ٱللَّهَ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٌ ١٠٦","ما ننسخ من آية أو ننسها نأت بخير منها أو مثلها ألم تعلم أن الله على كل شيء قدير","ތިމަންރަސްކަލާނގެ ނަސްޚުކުރައްވައިފި އާޔަތެއް، ނުވަތަ ތިމަންރަސްކަލާނގެ ހަނދުމަނައްތަވައިފި އާޔަތެއްގެ ބަދަލުގައި، އެއަށްވުރެ ހެޔޮ ނުވަތަ ހަމަ އެފަދަ އާޔަތެއް ތިމަންރަސްކަލާނގެ ގެނެސްދެއްވާ ހުށީމެވެ. ހަމަކަށަވަރުން، ކޮންމެ ކަމެއްގެ މައްޗަށް ﷲކުޅަދުންވަންތަވެވޮޑިގެންވާކަން ކަލޭގެފާނު ދެނެވަޑައި ނުގަންނަވަމުތޯއެވެ؟","",""],["₂ سورة البقرة","107","أَلَمۡ تَعۡلَمۡ أَنَّ ٱللَّهَ لَهُۥ مُلۡكُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِۗ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِن وَلِيّٖ وَلَا نَصِيرٍ ١٠٧","ألم تعلم أن الله له ملك السماوات والأرض وما لكم من دون الله من ولي ولا نصير","ހަމަކަށަވަރުން، އުޑުތަކާއި ބިމުގެ ވެރިކަން ﷲއަށް މިލްކުވެގެންވާ ކަމާއި، ﷲ ފިޔަވައި ތިޔަބައިމީހުންނަށް އެއްވެސް އެހީތެރިޔަކު އަދި ނަސްރު ދޭނޭ މީހަކުވެސް ނެތްކަން ކަލޭގެފާނު ދެނެވަޑައި ނުގަންނަވަމުތޯއެވެ؟","",""],["₂ سورة البقرة","108","أَمۡ تُرِيدُونَ أَن تَسۡـَٔلُواْ رَسُولَكُمۡ كَمَا سُئِلَ مُوسَىٰ مِن قَبۡلُۗ وَمَن يَتَبَدَّلِ ٱلۡكُفۡرَ بِٱلۡإِيمَٰنِ فَقَدۡ ضَلَّ سَوَآءَ ٱلسَّبِيلِ ١٠٨","أم تريدون أن تسألوا رسولكم كما سئل موسى من قبل ومن يتبدل الكفر بالإيمان فقد ضل سواء السبيل","އަދި ކިއެއްތަ! މީގެކުރިން މޫސާގެފާނާ ސުވާލުކުރި ފަދައިން، ތިޔަބައިމީހުންގެ ރަސޫލާއާ ސުވާލުކުރުމަށް ތިޔަބައިމީހުން އެދެނީހެއްޔެވެ؟ ކާފިރުކަމަށް އީމާން ކަން ބަދަލުކުރާ މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާޔަށް ހަމަ މަގު ގެއްލިއްޖެކަން ކަށަވަރެވެ.","",""],["₂ سورة البقرة","109","وَدَّ كَثِيرٞ مِّنۡ أَهۡلِ ٱلۡكِتَٰبِ لَوۡ يَرُدُّونَكُم مِّنۢ بَعۡدِ إِيمَٰنِكُمۡ كُفَّارًا حَسَدٗا مِّنۡ عِندِ أَنفُسِهِم مِّنۢ بَعۡدِ مَا تَبَيَّنَ لَهُمُ ٱلۡحَقُّۖ فَٱعۡفُواْ وَٱصۡفَحُواْ حَتَّىٰ يَأۡتِيَ ٱللَّهُ بِأَمۡرِهِۦٓۗ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٞ ١٠٩","ود كثير من أهل الكتاب لو يردونكم من بعد إيمانكم كفارا حسدا من عند أنفسهم من بعد ما تبين لهم الحق فاعفوا واصفحوا حتى يأتي الله بأمره إن الله على كل شيء قدير","ފޮތުގެ އަހުލުވެރިންގެ ތެރެއިން ގިނަމީހުން، އެއުރެންނަށް ހައްގު ބަޔާންވެ އެނގުމަށްފަހުގައި، އެއުރެން އަމިއްލައަށް ހަސަދަވެރިވެގެން، ތިޔަބައިމީހުން އީމާން ވުމަށްފަހު އަލުން އަނބުރާ ކާފިރުކަމަށް ރުޖޫއަކުރެވޭނެނަމައޭ ހިތައި އެކަމަށް އެދުނެވެ. ފަހެ، (އެއުރެންނާމެދުގައި ކަން ކުރަންވީގޮތް ބަޔާންކުރައްވައި) ﷲގެ އަމުރުފުޅު ފޮނުއްވައިފުމަށް ދާންދެން (އެއުރެންނަށް) ތިޔަބައިމީހުން މާފުކޮށް ދޫކޮށްލާށެވެ! ހަމަކަށަވަރުން، ﷲއީ ކޮންމެ ކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","110","وَأَقِيمُواْ ٱلصَّلَوٰةَ وَءَاتُواْ ٱلزَّكَوٰةَۚ وَمَا تُقَدِّمُواْ لِأَنفُسِكُم مِّنۡ خَيۡرٖ تَجِدُوهُ عِندَ ٱللَّهِۗ إِنَّ ٱللَّهَ بِمَا تَعۡمَلُونَ بَصِيرٞ ١١٠","وأقيموا الصلاة وآتوا الزكاة وما تقدموا لأنفسكم من خير تجدوه عند الله إن الله بما تعملون بصير","އަދި ތިޔަބައިމީހުން ނަމާދު ގާއިމުކުރާށެވެ! އަދި ތިޔަބައިމީހުން ޒަކާތް ދޭށެވެ! ހެޔޮކަމުގެ ތެރެއިން ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސު ތަކަށްޓަކައި ތިޔަބައިމީހުން އިސްކުޅަ ކޮންމެ ކަމެއްގެ ސަވާބު، ﷲގެ ހަޒުރަތުގައި ތިޔަބައިމީހުންނަށް ފެންނަހުށްޓެވެ. ހަމަކަށަވަރުން، ﷲއީ، ތިޔަބައިމީހުން ކުރާކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","111","وَقَالُواْ لَن يَدۡخُلَ ٱلۡجَنَّةَ إِلَّا مَن كَانَ هُودًا أَوۡ نَصَٰرَىٰۗ تِلۡكَ أَمَانِيُّهُمۡۗ قُلۡ هَاتُواْ بُرۡهَٰنَكُمۡ إِن كُنتُمۡ صَٰدِقِينَ ١١١","وقالوا لن يدخل الجنة إلا من كان هودا أو نصارى تلك أمانيهم قل هاتوا برهانكم إن كنتم صادقين","އެއުރެން ބުނޫއެވެ. ޔަހޫދީއަކު ކަމުގައި ނުވަތަ ނަސާރާއަކު ކަމުގައިވާ މީހަކު މެނުވީ، ސުވަރުގެޔަކަށް ނުވަންނާނެތެވެ. އެއީ، އެއުރެންގެ ދޮގު އުންމީދު ތަކެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންނީ، ތެދުބުނާ ބަޔަކު ކަމުގައިވަނީނަމަ، ތިޔަބައިމީހުން (އެކަމަށް) ދަލީލުގެންނާށެވެ!","",""],["₂ سورة البقرة","112","بَلَىٰۚ مَنۡ أَسۡلَمَ وَجۡهَهُۥ لِلَّهِ وَهُوَ مُحۡسِنٞ فَلَهُۥٓ أَجۡرُهُۥ عِندَ رَبِّهِۦ وَلَا خَوۡفٌ عَلَيۡهِمۡ وَلَا هُمۡ يَحۡزَنُونَ ١١٢","بلى من أسلم وجهه لله وهو محسن فله أجره عند ربه ولا خوف عليهم ولا هم يحزنون","އެހެންނަކުންނޫނެވެ! ހެޔޮކޮށް ކަންތައްކުރާ މީހަކު ކަމުގައިވާ ޙާލު، އެމީހެއްގެ މޫނު (އެބަހީ: މުޅި އެމީހާ) ﷲއަށް ކިޔަމަންކޮށްފި މީހަކަށް، ފަހެ، އޭނާގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި އޭނާގެ ދަރުމަހުށްޓެވެ. އަދި އެއުރެންގެ މައްޗަކަށް (އެއްވެސް) ބިރެއްނެތެވެ. އަދި އެއުރެންނީ، ހިތާމަކުރާނޭ ބަޔަކު ކަމުގައިވެސް ނުމެވޭމެއެވެ.","",""],["₂ سورة البقرة","113","وَقَالَتِ ٱلۡيَهُودُ لَيۡسَتِ ٱلنَّصَٰرَىٰ عَلَىٰ شَيۡءٖ وَقَالَتِ ٱلنَّصَٰرَىٰ لَيۡسَتِ ٱلۡيَهُودُ عَلَىٰ شَيۡءٖ وَهُمۡ يَتۡلُونَ ٱلۡكِتَٰبَۗ كَذَٰلِكَ قَالَ ٱلَّذِينَ لَا يَعۡلَمُونَ مِثۡلَ قَوۡلِهِمۡۚ فَٱللَّهُ يَحۡكُمُ بَيۡنَهُمۡ يَوۡمَ ٱلۡقِيَٰمَةِ فِيمَا كَانُواْ فِيهِ يَخۡتَلِفُونَ ١١٣","وقالت اليهود ليست النصارى على شيء وقالت النصارى ليست اليهود على شيء وهم يتلون الكتاب كذلك قال الذين لا يعلمون مثل قولهم فالله يحكم بينهم يوم القيامة فيما كانوا فيه يختلفون","ޔަހޫދީން ބުނެފޫއެވެ. ނަސާރާ އިން ތިބީ އެއްވެސް ގޮތެއްގެ މައްޗަކު ނޫނެވެ. އަދި ނަސާރާ އިން ބުނެފޫއެވެ. ޔަހޫދީން ތިބީ އެއްވެސް ގޮތެއްގެ މައްޗަކު ނޫނެވެ. (އެއުރެން އެހެން އެ ބުނަނީ) އެއުރެން ފޮތް (އެބަހީ: ތައުރާތާއި އިންޖީލު) ކިޔަވައިއުޅޭ ޙާލު ގައެވެ. ހަމައެފަދައިން، ނުދަންނަ މީހުން (އެބަހީ: އަރަބީންގެ ކާފިރުން) ވެސްބުނީ، އެއުރެންގެ ބުނުންފަދައިންނެވެ. ފަހެ، އެއުރެން ޚިލާފުވެ އުޅުނު ކަންތަކާމެދު ގިޔާމަތް ދުވަހުން އެއުރެންގެ މެދުގައި ﷲ ހުކުމްކުރައްވާނެތެވެ.","",""],["₂ سورة البقرة","114","وَمَنۡ أَظۡلَمُ مِمَّن مَّنَعَ مَسَٰجِدَ ٱللَّهِ أَن يُذۡكَرَ فِيهَا ٱسۡمُهُۥ وَسَعَىٰ فِي خَرَابِهَآۚ أُوْلَـٰٓئِكَ مَا كَانَ لَهُمۡ أَن يَدۡخُلُوهَآ إِلَّا خَآئِفِينَۚ لَهُمۡ فِي ٱلدُّنۡيَا خِزۡيٞ وَلَهُمۡ فِي ٱلۡأٓخِرَةِ عَذَابٌ عَظِيمٞ ١١٤","ومن أظلم ممن منع مساجد الله أن يذكر فيها اسمه وسعى في خرابها أولئك ما كان لهم أن يدخلوها إلا خائفين لهم في الدنيا خزي ولهم في الآخرة عذاب عظيم","ﷲގެ މިސްކިތްތަކުގައި އެކަލާނގެ އިސްމުފުޅު ނަންގަތުން މަނާކޮށް، އަދި އެތަންތަން (ފަޅުކޮށް) ހަރާބުކުރުމަށް މަސައްކަތްކޮށްފި މީހަކަށްވުރެ އަނިޔާވެރިކަންބޮޑީ ކާކުހެއްޔެވެ؟ އެއުރެން ބިރުންތިބޭ ޙާލުގައި މެނުވީ، އެތަންތަނަށް ވަދެއުޅުމެއް އެއުރެންނަކަށް ނުވެއެވެ. ދުނިޔޭގައި އެއުރެންނަށްހުރީ ނިކަމެތިކަމެވެ. އަދި އާޚިރަތުގައި އެއުރެންނަށް ހުރީ ބޮޑުވެގެންވާ އަޒާބެވެ.","",""],["₂ سورة البقرة","115","وَلِلَّهِ ٱلۡمَشۡرِقُ وَٱلۡمَغۡرِبُۚ فَأَيۡنَمَا تُوَلُّواْ فَثَمَّ وَجۡهُ ٱللَّهِۚ إِنَّ ٱللَّهَ وَٰسِعٌ عَلِيمٞ ١١٥","ولله المشرق والمغرب فأينما تولوا فثم وجه الله إن الله واسع عليم","މަޝްރިގާއި މަޣްރިބު މިލްކުވެގެންވަނީ، ﷲއަށެވެ. ފަހެ، ތިޔަބައިމީހުން ކޮންމެ ފަރާތަކަށް އެނބުރުނަސް، އެތަނެއްގައި ﷲ ވޮޑިގެންވެއެވެ. ހަމަކަށަވަރުން، ﷲއީ، ތަނަވަސްވަންތަ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","116","وَقَالُواْ ٱتَّخَذَ ٱللَّهُ وَلَدٗاۗ سُبۡحَٰنَهُۥۖ بَل لَّهُۥ مَا فِي ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِۖ كُلّٞ لَّهُۥ قَٰنِتُونَ ١١٦","وقالوا اتخذ الله ولدا سبحانه بل له ما في السماوات والأرض كل له قانتون","ﷲ، ދަރިކަލަކު ހިއްޕެވިކަމަށް އެއުރެން ބުނެފޫއެވެ. (އެބަހީ: ﷲއަށް ދަރިކަލަކު ވާކަމަށް ޔަހޫދީންނާއި ނަސާރާ އިންނާއި މުޝްރިކުން ބުނޫއެވެ.) އެކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! އަދި ކިއެއްތަ! އުޑުތަކާއި ބިމުގައިވާހާ ތަކެއްޗަކާއި ކަމެއް މިލްކުވެގެންވަނީ، އެކަލާނގެއަށެވެ. އެންމެހާ ތަކެއްޗާއި ކަންތައް އެކަލާނގެއަށް ކިޔަމަންވެ، އަޅުވެތިވެގެންވެއެވެ.","",""],["₂ سورة البقرة","117","بَدِيعُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِۖ وَإِذَا قَضَىٰٓ أَمۡرٗا فَإِنَّمَا يَقُولُ لَهُۥ كُن فَيَكُونُ ١١٧","بديع السماوات والأرض وإذا قضى أمرا فإنما يقول له كن فيكون","(އެކަލާނގެއީ) އިސްވެދިޔަ މިސާލަކާނުލައި އުޑުތަކާއި ބިން ހެއްދެވި ރަސްކަލާނގެއެވެ. އެކަލާނގެ ކަމަކަށް ނިޔާކުރައްވައިފިނަމަ، އެކަމަކަށް ވަހީކުރައްވާކަން ކަށަވަރީ، [ވާށޭ] އެވެ! ދެން އެކަމެއް ވެދެއެވެ.","",""],["₂ سورة البقرة","118","وَقَالَ ٱلَّذِينَ لَا يَعۡلَمُونَ لَوۡلَا يُكَلِّمُنَا ٱللَّهُ أَوۡ تَأۡتِينَآ ءَايَةٞۗ كَذَٰلِكَ قَالَ ٱلَّذِينَ مِن قَبۡلِهِم مِّثۡلَ قَوۡلِهِمۡۘ تَشَٰبَهَتۡ قُلُوبُهُمۡۗ قَدۡ بَيَّنَّا ٱلۡأٓيَٰتِ لِقَوۡمٖ يُوقِنُونَ ١١٨","وقال الذين لا يعلمون لولا يكلمنا الله أو تأتينا آية كذلك قال الذين من قبلهم مثل قولهم تشابهت قلوبهم قد بينا الآيات لقوم يوقنون","އަދި ނުދަންނަ މީހުން ބުނެފޫއެވެ. ﷲ (ސީދާ) ތިމަންމެންނަށް ބަސް ވަހީ ނުކުރައްވަނީ، ކީއްވެގެން ބާވައެވެ! ނުވަތަ (މުޙައްމަދުގެފާނުގެ ބަސްފުޅު ތެދުކަމުގެ) ހެތްކެއް ތިމަންމެންގެ ގާތަށް ނާންނަނީ، ކީއްވެގެން ބާވައެވެ! ހަމައެފަދައިން، އެއުރެންގެ ކުރިން އުޅުނު އުއްމަތްތަކުގެ މީހުން ބުނީވެސް، އެއުރެންގެ ބުނުމާ އެއްފަދަ ބުނުމެކެވެ. އެއުރެންގެ ހިތްތައްވަނީ އެއްގޮތްވެގެންނެވެ. (އެފަދަ ކަންތައް) ޔަގީންކުރާ މީހުންނަށް، ހަމަކަށަވަރުން ތިމަންރަސްކަލާނގެ ހެކިތައް ބަޔާންކުރައްވައި އެންގެވީމެވެ.","",""],["₂ سورة البقرة","119","إِنَّآ أَرۡسَلۡنَٰكَ بِٱلۡحَقِّ بَشِيرٗا وَنَذِيرٗاۖ وَلَا تُسۡـَٔلُ عَنۡ أَصۡحَٰبِ ٱلۡجَحِيمِ ١١٩","إنا أرسلناك بالحق بشيرا ونذيرا ولا تسأل عن أصحاب الجحيم","އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު ކަމުގައްޔާއި ބިރުވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު ކަމުގައި، ހައްގު ދީނާއިގެން ހަމަކަށަވަރުން ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ފޮނުއްވީމެވެ. ފަހެ، ނަރަކައިގެ އަހުލުވެރިންނާމެދު ކަލޭގެފާނަކާ ސުވާލެއް ނުކުރައްވާނެތެވެ.","",""],["₂ سورة البقرة","120","وَلَن تَرۡضَىٰ عَنكَ ٱلۡيَهُودُ وَلَا ٱلنَّصَٰرَىٰ حَتَّىٰ تَتَّبِعَ مِلَّتَهُمۡۗ قُلۡ إِنَّ هُدَى ٱللَّهِ هُوَ ٱلۡهُدَىٰۗ وَلَئِنِ ٱتَّبَعۡتَ أَهۡوَآءَهُم بَعۡدَ ٱلَّذِي جَآءَكَ مِنَ ٱلۡعِلۡمِ مَا لَكَ مِنَ ٱللَّهِ مِن وَلِيّٖ وَلَا نَصِيرٍ ١٢٠","ولن ترضى عنك اليهود ولا النصارى حتى تتبع ملتهم قل إن هدى الله هو الهدى ولئن اتبعت أهواءهم بعد الذي جاءك من العلم ما لك من الله من ولي ولا نصير","އަދި ޔަހޫދީ ންވެސް ނަސާރާ އިންވެސް އެއުރެންގެ ދީނަށް ކަލޭގެފާނު ތަބާ ވެވަޑައިގެންފުމަށް ދާނދެން ކަލޭގެފާނަކާ ނުރުހޭނެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން ﷲގެ މަގު އެއީ ހަމަ ތެދުމަގެވެ. އަދި ކަށަވަރުންވެސް، ކަލޭގެފާނުގެ އަރިހަށް އިލްމުގެ ތެރެއިން އައި ކަންތަކަށްފަހު އެއުރެންގެ އެދުންތަކަށް ކަލޭގެފާނު ތަބާ ވެވަޑައިގެންފިނަމަ، ﷲގެ ހަޒުރަތުން ކަލޭގެފާނަށް އެއްވެސް އެހީތެރިޔަކު އަދި ނަސްރު ދޭނޭ މީހަކުވެސް ނުވާނެތެވެ.","",""],["₂ سورة البقرة","121","ٱلَّذِينَ ءَاتَيۡنَٰهُمُ ٱلۡكِتَٰبَ يَتۡلُونَهُۥ حَقَّ تِلَاوَتِهِۦٓ أُوْلَـٰٓئِكَ يُؤۡمِنُونَ بِهِۦۗ وَمَن يَكۡفُرۡ بِهِۦ فَأُوْلَـٰٓئِكَ هُمُ ٱلۡخَٰسِرُونَ ١٢١","الذين آتيناهم الكتاب يتلونه حق تلاوته أولئك يؤمنون به ومن يكفر به فأولئك هم الخاسرون","ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ފޮތް ދެއްވި މީހުން އެފޮތް ކިޔަވަންވީ ހައްގު ގޮތުގައި އެފޮތް ކިޔަވައި އުޅެތެވެ. އެއުރެން އެ ފޮތަށް އީމާން ވެތެވެ. އަދި އެފޮތަށް ކާފިރުވާ މީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ ހަމަ ގެއްލެނިވެގެންވާ މީހުންނެވެ.","",""],["₂ سورة البقرة","122","يَٰبَنِيٓ إِسۡرَـٰٓءِيلَ ٱذۡكُرُواْ نِعۡمَتِيَ ٱلَّتِيٓ أَنۡعَمۡتُ عَلَيۡكُمۡ وَأَنِّي فَضَّلۡتُكُمۡ عَلَى ٱلۡعَٰلَمِينَ ١٢٢","يا بني إسرائيل اذكروا نعمتي التي أنعمت عليكم وأني فضلتكم على العالمين","އޭ އިސްރާއީލުގެދަރިންނޭވެ! ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް ދެއްވި ނިއުމަތާއި، އަދި (އެދުވަސްވަރުގެ) މީސްތަކުންގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން މާތްކުރައްވާފައިވާކަން ހަނދުމަކުރާށެވެ!","",""],["₂ سورة البقرة","123","وَٱتَّقُواْ يَوۡمٗا لَّا تَجۡزِي نَفۡسٌ عَن نَّفۡسٖ شَيۡـٔٗا وَلَا يُقۡبَلُ مِنۡهَا عَدۡلٞ وَلَا تَنفَعُهَا شَفَٰعَةٞ وَلَا هُمۡ يُنصَرُونَ ١٢٣","واتقوا يوما لا تجزي نفس عن نفس شيئا ولا يقبل منها عدل ولا تنفعها شفاعة ولا هم ينصرون","އެދުވަހަކުން އެއްވެސް ނަފްސަކަށް އެއްވެސް ނަފްސެއްގެ ކިބައިން އެއްވެސް ކަމެއް ފުއްދައިނުދެވޭނޭ އަދި އެކެއްގެ ކިބައިން ފިދުޔެއްވެސް ނުހިއްޕަވާނޭ އަދި (އެއްވެސް ފަރާތެއްގެ) ޝަފާއަތަކުން އެއްވެސް މީހަކަށް މަންފާއެއް ނުކުރާނޭ އަދި އެއުރެންނަށް (އެއްވެސް ފަރާތަކުން) ނަސްރެއް ނުލިބޭނޭ ދުވަހަކަށް ތިޔަބައިމީހުން ބިރުވެތިވެ ރައްކާތެރިވާށެވެ!","",""],["₂ سورة البقرة","124","۞وَإِذِ ٱبۡتَلَىٰٓ إِبۡرَٰهِـۧمَ رَبُّهُۥ بِكَلِمَٰتٖ فَأَتَمَّهُنَّۖ قَالَ إِنِّي جَاعِلُكَ لِلنَّاسِ إِمَامٗاۖ قَالَ وَمِن ذُرِّيَّتِيۖ قَالَ لَا يَنَالُ عَهۡدِي ٱلظَّـٰلِمِينَ ١٢٤","وإذ ابتلى إبراهيم ربه بكلمات فأتمهن قال إني جاعلك للناس إماما قال ومن ذريتي قال لا ينال عهدي الظالمين","އިބްރާހީމްގެފާނުގެ ވެރިރަސްކަލާނގެ، ކަލިމަ ތަކަކުން (އެބަހީ: ކުރެއްވި އަމުރު ފުޅުތަކަކާއި ނަހީތަކަކުން އެކަލޭގެފާނުގެ ކިޔަމަންތެރިކަންހުރި މިންވަރު ބެއްލެވުމަށް) އިމްތިހާނުކުރެއްވިހިނދު ހަނދުމަކުރައްވާށެވެ! ފަހެ، އެކަލޭގެފާނު (ކިޔަމަންތެރިވެވަޑައިގެން) އެކަންތައްތައް ފުރިހަމަ ކުރެއްވިއެވެ. އެކަލާނގެ (އެކަލޭގެފާނަށް) ވަހީކުރެއްވިއެވެ. ހަމަކަށަވަރުން، މީސްތަކުންނަށް އިމާމަކު ކަމުގައި ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ލައްވާހުށީމެވެ. އެކަލޭގެފާނު ދެންނެވިއެވެ. ތިމަންއަޅާގެ ދަރިފަސްކޮޅުންވެސް މެއެވެ. އެކަލާނގެ ވަހީކުރެއްވިއެވެ. އަނިޔާވެރިންނަކަށް ތިމަންރަސްކަލާނގެ އަހުދެއް ނުލިބޭނެތެވެ.","",""],["₂ سورة البقرة","125","وَإِذۡ جَعَلۡنَا ٱلۡبَيۡتَ مَثَابَةٗ لِّلنَّاسِ وَأَمۡنٗا وَٱتَّخِذُواْ مِن مَّقَامِ إِبۡرَٰهِـۧمَ مُصَلّٗىۖ وَعَهِدۡنَآ إِلَىٰٓ إِبۡرَٰهِـۧمَ وَإِسۡمَٰعِيلَ أَن طَهِّرَا بَيۡتِيَ لِلطَّآئِفِينَ وَٱلۡعَٰكِفِينَ وَٱلرُّكَّعِ ٱلسُّجُودِ ١٢٥","وإذ جعلنا البيت مثابة للناس وأمنا واتخذوا من مقام إبراهيم مصلى وعهدنا إلى إبراهيم وإسماعيل أن طهرا بيتي للطائفين والعاكفين والركع السجود","އަދި ސަވާބު ލިބިގަތުމުގެ ތަނެއް ކަމުގައްޔާއި އަމާން ކަން ލިބިގެންވާ ތަނެއް ކަމުގައި މީސްތަކުންނަށްޓަކައި ތިމަންރަސްކަލާނގެ ކައުބަތުﷲގެފުޅު ލެއްވިހިނދު ހަނދުމަކުރައްވާށެވެ! އަދި އިބްރާހީމްގެފާނު ހުންނެވިތަން (އެބަހީ: ނަމާދު ކުރެއްވުމަށް ނުވަތަ ގެފުޅު ބިނާކުރެއްވުމަށް ހުންނެވިތަން) އެއީ ތިޔަބައިމީހުން ނަމާދުކުރާ ތަނެއްކަމުގައި ބަލައި، ބޭނުން ހިފާށެވެ! އަދި އިބްރާހީމްގެފާނާއި އިސްމާޢީލުގެފާނަށް ތިމަންރަސްކަލާނގެ އެންގެވީމެވެ. ތަވާފުކުރާ މީހުންނާއި އަޅުކަންކުރުމަށްތިބޭ މީހުންނާއި ރުކޫއު ސުޖޫދުކުރާ މީހުންނަށްޓަކައި ތިޔަ ދެބަފައިކަލުން ތިމަންރަސްކަލާނގެ ގެފުޅު ތާހިރުކުރައްވާށެވެ!","",""],["₂ سورة البقرة","126","وَإِذۡ قَالَ إِبۡرَٰهِـۧمُ رَبِّ ٱجۡعَلۡ هَٰذَا بَلَدًا ءَامِنٗا وَٱرۡزُقۡ أَهۡلَهُۥ مِنَ ٱلثَّمَرَٰتِ مَنۡ ءَامَنَ مِنۡهُم بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِۚ قَالَ وَمَن كَفَرَ فَأُمَتِّعُهُۥ قَلِيلٗا ثُمَّ أَضۡطَرُّهُۥٓ إِلَىٰ عَذَابِ ٱلنَّارِۖ وَبِئۡسَ ٱلۡمَصِيرُ ١٢٦","وإذ قال إبراهيم رب اجعل هذا بلدا آمنا وارزق أهله من الثمرات من آمن منهم بالله واليوم الآخر قال ومن كفر فأمتعه قليلا ثم أضطره إلى عذاب النار وبئس المصير","އަދި އިބްރާހީމްގެފާނު ދުއާކުރައްވައި ވިދާޅުވިހިނދު ހަނދުމަކުރައްވާށެވެ! އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! މިރަށަކީ އަމާން ކަން ލިބިގެންވާ ރަށެއްކަމުގައި ލައްވައިފާނދޭވެ! އަދި އެރަށުގެ އަހުލުވެރިންކުރެ ﷲއަށާއި އާޚިރަތް ދުވަހަށް އީމާންވި މީހުންނަށް މޭވާތަކުން ރިޒްގު ދެއްވައިފާނދޭވެ! އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ކާފިރު ވެއްޖެ މީހާއަށް (ދުނިޔޭގައި) ކުޑަހިނދުކޮޅެއްގެ އުފަލާއި އަރާމު، ތިމަންރަސްކަލާނގެ ދެއްވާހުށީމެވެ. ދެން، ނަރަކައިގެ އަޒާބުގެ ތެރެޔަށް އެމީހަކު ފޮނުއްވައިލައްވާހުށީމެވެ. އެއީ ހާދަހާ ނުބައިވެގެންވާ ނިމިދިޔުމެކެވެ.","",""],["₂ سورة البقرة","127","وَإِذۡ يَرۡفَعُ إِبۡرَٰهِـۧمُ ٱلۡقَوَاعِدَ مِنَ ٱلۡبَيۡتِ وَإِسۡمَٰعِيلُ رَبَّنَا تَقَبَّلۡ مِنَّآۖ إِنَّكَ أَنتَ ٱلسَّمِيعُ ٱلۡعَلِيمُ ١٢٧","وإذ يرفع إبراهيم القواعد من البيت وإسماعيل ربنا تقبل منا إنك أنت السميع العليم","އަދި އިބްރާހީމްގެފާނާއި އިސްމާޢީލުގެފާނާ ދެބަފައިކަލުން ގެފުޅުގެ ބިންގާ އުފުއްލަވައި ބިނާކުރައްވަމުން ގެންދެވިހިނދު، ހަނދުމަކުރާށެވެ! (އެހިނދު ދުއާކުރެއްވިއެވެ.) އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެންގެ ކިބައިން (މިކަން) ގަބޫލުކުރައްވައިފާނދޭވެ! ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ މޮޅަށް އައްސަވާވޮޑިގެންވާ މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","128","رَبَّنَا وَٱجۡعَلۡنَا مُسۡلِمَيۡنِ لَكَ وَمِن ذُرِّيَّتِنَآ أُمَّةٗ مُّسۡلِمَةٗ لَّكَ وَأَرِنَا مَنَاسِكَنَا وَتُبۡ عَلَيۡنَآۖ إِنَّكَ أَنتَ ٱلتَّوَّابُ ٱلرَّحِيمُ ١٢٨","ربنا واجعلنا مسلمين لك ومن ذريتنا أمة مسلمة لك وأرنا مناسكنا وتب علينا إنك أنت التواب الرحيم","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އިބަރަސްކަލާނގެއަށް ފުރިހަމަޔަށް ކިޔަމަންވާ ދެމީހުން ކަމުގައި އަޅަމެން ލައްވައިފާނދޭވެ! އަދި އިބަރަސްކަލާނގެއަށް ފުރިހަމަޔަށް ކިޔަމަންވާ އުއްމަތެއް، އަޅަމެންގެ ދަރިފަސްކޮޅުން ލައްވައިފާނދޭވެ! އަދި އަޅަމެން އަޅުކަންކުރާނޭ ގޮތްތައް އަޅަމެންނަށް ދައްކަވައިފާނދޭވެ! އަދި އަޅަމެންގެ މައްޗަށް ތައުބާ ލައްވައިފާނދޭވެ! ހަމަކަށަވަރުން އިބަރަސްކަލާނގެއީ ގިނަގިނައިން ތައުބާ ލައްވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","129","رَبَّنَا وَٱبۡعَثۡ فِيهِمۡ رَسُولٗا مِّنۡهُمۡ يَتۡلُواْ عَلَيۡهِمۡ ءَايَٰتِكَ وَيُعَلِّمُهُمُ ٱلۡكِتَٰبَ وَٱلۡحِكۡمَةَ وَيُزَكِّيهِمۡۖ إِنَّكَ أَنتَ ٱلۡعَزِيزُ ٱلۡحَكِيمُ ١٢٩","ربنا وابعث فيهم رسولا منهم يتلو عليهم آياتك ويعلمهم الكتاب والحكمة ويزكيهم إنك أنت العزيز الحكيم","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަދި އެ އުއްމަތްގެ މީހުންނަށް އިބަރަސްކަލާނގެ އާޔަތްތައް ކިޔަވައިދެއްވާ، ހިކުމަތާއި ފޮތް އުނގަންނައިދެއްވާ އަދި (އެންމެހާ ނުބައިގޮތްތަކުން) އެ އުއްމަތް ތާހިރުކުރައްވާނޭ ރަސޫލަކު، އެ އުއްމަތްގެ ތެރެއިން، އެ އުއްމަތްގެ ތެރެޔަށް ފޮނުއްވައިފާނދޭވެ! ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","130","وَمَن يَرۡغَبُ عَن مِّلَّةِ إِبۡرَٰهِـۧمَ إِلَّا مَن سَفِهَ نَفۡسَهُۥۚ وَلَقَدِ ٱصۡطَفَيۡنَٰهُ فِي ٱلدُّنۡيَاۖ وَإِنَّهُۥ فِي ٱلۡأٓخِرَةِ لَمِنَ ٱلصَّـٰلِحِينَ ١٣٠","ومن يرغب عن ملة إبراهيم إلا من سفه نفسه ولقد اصطفيناه في الدنيا وإنه في الآخرة لمن الصالحين","އެމީހެއްގެ ނަފްސު އިހާނެތި ކޮށްލައިފި މީހަކު މެނުވީ، އިބްރާހީމްގެފާނުގެ ދީނަށް ނުރުހުންވެ، އެ ދީނުން ދުރުވެގަންނާނީ ކާކުހެއްޔެވެ؟ ހަމަކަށަވަރުން، ދުނިޔޭގައިވެސް ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނު ހޮއްވަވައި ޚިޔާރުކުރެއްވީމެވެ. އަދި އެކަލޭގެފާނީ، އާޚިރަތް ދުވަހުން ސާލިހުންގެ ތެރެއިންވާ ބޭކަލަކުކަން ކަށަވަރެވެ.","",""],["₂ سورة البقرة","131","إِذۡ قَالَ لَهُۥ رَبُّهُۥٓ أَسۡلِمۡۖ قَالَ أَسۡلَمۡتُ لِرَبِّ ٱلۡعَٰلَمِينَ ١٣١","إذ قال له ربه أسلم قال أسلمت لرب العالمين","އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެކަލޭގެފާނަށް، [ކަލޭގެފާނު ކިޔަމަންވެ ވަޑައިގަންނަވާށޭ] ވަހީކުރެއްވިހިނދު ހަނދުމަކުރައްވާށެވެ! އެކަލޭގެފާނު ދެންނެވިއެވެ. އާލަމްތަކުގެ ވެރިރަސްކަލާނގެއަށް ތިމަންއަޅާ ކިޔަމަންވެއްޖައީމެވެ.","",""],["₂ سورة البقرة","132","وَوَصَّىٰ بِهَآ إِبۡرَٰهِـۧمُ بَنِيهِ وَيَعۡقُوبُ يَٰبَنِيَّ إِنَّ ٱللَّهَ ٱصۡطَفَىٰ لَكُمُ ٱلدِّينَ فَلَا تَمُوتُنَّ إِلَّا وَأَنتُم مُّسۡلِمُونَ ١٣٢","ووصى بها إبراهيم بنيه ويعقوب يا بني إن الله اصطفى لكم الدين فلا تموتن إلا وأنتم مسلمون","އެކަމަށް އިބްރާހީމްގެފާނު އެކަލޭގެފާނުގެ ދަރިދަރިކަލުންނަށް ވަސިއްޔަތްކުރެއްވިއެވެ. އަދި ޔައުގޫބުގެފާނުވެސް މެއެވެ. އޭ އަހުރެންގެ ދަރިންނޭވެ! ހަމަކަށަވަރުން، ﷲ ތިޔަބައިމީހުންނަށްޓަކައި ދީން ހޮއްވަވައި ޚިޔާރުކުރައްވައިފިއެވެ. ފަހެ، (އެކަލާނގެއަށް) ކިޔަމަންވެތިބޭ ޙާލުގައި މެނުވީ، ތިޔަބައިމީހުން މަރުނުވާށެވެ!","",""],["₂ سورة البقرة","133","أَمۡ كُنتُمۡ شُهَدَآءَ إِذۡ حَضَرَ يَعۡقُوبَ ٱلۡمَوۡتُ إِذۡ قَالَ لِبَنِيهِ مَا تَعۡبُدُونَ مِنۢ بَعۡدِيۖ قَالُواْ نَعۡبُدُ إِلَٰهَكَ وَإِلَٰهَ ءَابَآئِكَ إِبۡرَٰهِـۧمَ وَإِسۡمَٰعِيلَ وَإِسۡحَٰقَ إِلَٰهٗا وَٰحِدٗا وَنَحۡنُ لَهُۥ مُسۡلِمُونَ ١٣٣","أم كنتم شهداء إذ حضر يعقوب الموت إذ قال لبنيه ما تعبدون من بعدي قالوا نعبد إلهك وإله آبائك إبراهيم وإسماعيل وإسحاق إلها واحدا ونحن له مسلمون","ނުވަތަ ޔައުގޫބުގެފާނުގެ އަރިހަށް މަރުއައިސް ޙާޒިރުު ވިހިނދު ތިޔަބައިމީހުން ޙާޒިރުުވެ ދެކެންތިބީމުހެއްޔެވެ؟ އެހިނދު އެކަލޭގެފާނުގެ ދަރިދަރިކަލުންނަށް އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިމަން މަރުވެދިޔުމަށްފަހު ތިޔަބައިމީހުން އަޅުކަންކުރާނީ ކޮންފަރާތަކަށް ހެއްޔެވެ؟ އެއުރެން ދެންނެވޫއެވެ. ތިމަންމެން އަޅުކަންކުރާނީ، ކަލޭގެފާނުގެ އިލާހަށެވެ. އަދި ކަލޭގެފާނުގެ ކާބަފައިކަލުނަވި އިބްރާހީމްގެފާނާއި އިސްމާޢީލުގެފާނާއި އިސްޙާގުގެފާނުގެ އިލާހަށެވެ. އެއީ، އެއްކައުވަންތަ ކަލާނގެއެވެ. ތިމަންމެން މިތިބީ، އެކަލާނގެއަށް ކިޔަމަންވެ މުސްލިމުން ކަމުގައި ވެގެންނެވެ.","",""],["₂ سورة البقرة","134","تِلۡكَ أُمَّةٞ قَدۡ خَلَتۡۖ لَهَا مَا كَسَبَتۡ وَلَكُم مَّا كَسَبۡتُمۡۖ وَلَا تُسۡـَٔلُونَ عَمَّا كَانُواْ يَعۡمَلُونَ ١٣٤","تلك أمة قد خلت لها ما كسبت ولكم ما كسبتم ولا تسألون عما كانوا يعملون","އެއީ، ހަމަކަށަވަރުން ފާއިތުވެހިނގައްޖެ އުއްމަތެކެވެ. އެ އުއްމަތް ހޯދިކަމެއް އެ އުއްމަތަށެވެ. އަދި ތިޔަބައިމީހުން ހޯދިކަމެއް ތިޔަބައިމީހުންނަށެވެ. އަދި އެއުރެން ކޮށްއުޅުނު ކަންތަކާމެދު ތިޔަބައިމީހުންނަކާ ސުވާލެއް ނުކުރައްވާހުށްޓެވެ.","",""],["₂ سورة البقرة","135","وَقَالُواْ كُونُواْ هُودًا أَوۡ نَصَٰرَىٰ تَهۡتَدُواْۗ قُلۡ بَلۡ مِلَّةَ إِبۡرَٰهِـۧمَ حَنِيفٗاۖ وَمَا كَانَ مِنَ ٱلۡمُشۡرِكِينَ ١٣٥","وقالوا كونوا هودا أو نصارى تهتدوا قل بل ملة إبراهيم حنيفا وما كان من المشركين","އެއުރެން (އެބަހީ: ޔަހޫދީންނާއި ނަސާރާ އިން) ބުނެފޫއެވެ. ތިޔަބައިމީހުން ޔަހޫދީން ކަމުގައި ނުވަތަ ނަސާރާ އިން ކަމުގައި ވާށެވެ! ތިޔަބައިމީހުންނަށް ތެދުމަގު ލިބޭނީ އޭރުންނެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އަދި ކީއްހެއްޔެވެ؟ (ތިމަންމެން ތަބާ ވާނީ) ބާތިލުގެ މަގުން އެއްކިބާވެ ހައްގުގެ މަގަށް ތަބާ ވެގެންވާ އިބްރާހީމްގެފާނުގެ ދީނަށެވެ. އަދި ޝަރީކުކުރާ މީހުންގެ ތެރެއިން އެކަލޭގެފާނެއް ނުވެއެވެ.","",""],["₂ سورة البقرة","136","قُولُوٓاْ ءَامَنَّا بِٱللَّهِ وَمَآ أُنزِلَ إِلَيۡنَا وَمَآ أُنزِلَ إِلَىٰٓ إِبۡرَٰهِـۧمَ وَإِسۡمَٰعِيلَ وَإِسۡحَٰقَ وَيَعۡقُوبَ وَٱلۡأَسۡبَاطِ وَمَآ أُوتِيَ مُوسَىٰ وَعِيسَىٰ وَمَآ أُوتِيَ ٱلنَّبِيُّونَ مِن رَّبِّهِمۡ لَا نُفَرِّقُ بَيۡنَ أَحَدٖ مِّنۡهُمۡ وَنَحۡنُ لَهُۥ مُسۡلِمُونَ ١٣٦","قولوا آمنا بالله وما أنزل إلينا وما أنزل إلى إبراهيم وإسماعيل وإسحاق ويعقوب والأسباط وما أوتي موسى وعيسى وما أوتي النبيون من ربهم لا نفرق بين أحد منهم ونحن له مسلمون","ތިޔަބައިމީހުން ބުނާށެވެ! ތިމަންމެން ﷲއަށާއި ތިމަންމެންނަށް ބާވައިލައްވައިފައިވާ ފޮތަށާއި އަދި އިބްރާހީމްގެފާނަށާއި އިސްމާޢީލުގެފާނަށާއި އިސްޙާގުގެފާނަށާއި، ޔައުގޫބުގެފާނަށާއި ޔައުގޫބުގެފާނުގެ އަސްބާޠުންނަށް ބާވައިލައްވައިފައިވާ ފޮތްފޮތަށާއި އަދި މޫސާގެފާނަށާއި ޢީސާގެފާނަށް ދެއްވާފައިވާ ފޮތަށާއި އަދި (އެހެނިހެން) ނަބިއްޔުންނަށް، އެބޭކަލުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ދެއްވާފައިވާ ފޮތްފޮތަށް އީމާން ވީމުއެވެ. ތިމަންމެން އެއިން އެއްވެސް ބޭކަލަކާމެދު ތަފާތެއް ނުކުރަމުއެވެ. އަދި ތިމަންމެންނީ، އެކަލާނގެއަށް ކިޔަމަންވެގެންތިބި ބަޔަކީމުއެވެ.","",""],["₂ سورة البقرة","137","فَإِنۡ ءَامَنُواْ بِمِثۡلِ مَآ ءَامَنتُم بِهِۦ فَقَدِ ٱهۡتَدَواْۖ وَّإِن تَوَلَّوۡاْ فَإِنَّمَا هُمۡ فِي شِقَاقٖۖ فَسَيَكۡفِيكَهُمُ ٱللَّهُۚ وَهُوَ ٱلسَّمِيعُ ٱلۡعَلِيمُ ١٣٧","فإن آمنوا بمثل ما آمنتم به فقد اهتدوا وإن تولوا فإنما هم في شقاق فسيكفيكهم الله وهو السميع العليم","ފަހެ، ތިޔަބައިމީހުން އީމާން ވެގެންތިބި ފަދައިން އެއުރެން އީމާން ވިނަމަ، އެއުރެންނަށް ތެދުމަގު ލިބުނީސްކަން ކަށަވަރެވެ. އަދި އެއުރެން އެނބުރި ފުރަގަސްދީފިނަމަ، އެއުރެން ވާކަން ކަށަވަރީ، ދެކޮޅުވެރި ކަމެއްގެ ތެރޭގައެވެ. ފަހެ، ﷲއެއުރެންގެ ކިބައިން ކަލޭގެފާނު ރައްކާތެރި ކުރައްވައި ސަލާމަތްކަން ދެއްވާނެތެވެ. އެކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","138","صِبۡغَةَ ٱللَّهِ وَمَنۡ أَحۡسَنُ مِنَ ٱللَّهِ صِبۡغَةٗۖ وَنَحۡنُ لَهُۥ عَٰبِدُونَ ١٣٨","صبغة الله ومن أحسن من الله صبغة ونحن له عابدون","ﷲގެ ދީނަށެވެ. (އެބަހީ: ތަބާ ވާންވީ ﷲގެ ދީނަށެވެ.) ހިދާޔަތާއި އިރްޝާދު ދެއްވުމުގައި ﷲއަށްވުރެ މޮޅީ ކާކުހެއްޔެވެ؟ އަދި ތިމަންމެންނީ، ހަމައެކަނި އެކަލާނގެއަށް އަޅުކަންކުރާ މީހުންނެވެ.","",""],["₂ سورة البقرة","139","قُلۡ أَتُحَآجُّونَنَا فِي ٱللَّهِ وَهُوَ رَبُّنَا وَرَبُّكُمۡ وَلَنَآ أَعۡمَٰلُنَا وَلَكُمۡ أَعۡمَٰلُكُمۡ وَنَحۡنُ لَهُۥ مُخۡلِصُونَ ١٣٩","قل أتحاجوننا في الله وهو ربنا وربكم ولنا أعمالنا ولكم أعمالكم ونحن له مخلصون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲއާމެދު ތިޔަބައިމީހުން ތިމަންމެންނާ ޖަދަލުކުރަނީހެއްޔެވެ؟ އެކަލާނގެއީ ތިމަންމެންގެ ވެރިރަސްކަލާނގެއެވެ. އަދި ތިޔަބައިމީހުންގެވެސް ވެރިރަސްކަލާނގެއެވެ. އަދި ތިމަންމެންގެ ޢަމަލުތައް ހުރީ (އެބަހީ: ތިމަންމެން ކުޅަކަމެއްގެ ޖަޒާ ހުރީ) ތިމަންމެންނަށެވެ. އަދި ތިޔަބައިމީހުންގެ ޢަމަލުތައް ހުރީ (އެބަހީ: ތިޔަބައިމީހުން ކުޅަކަމެއްގެ ޖަޒާ ހުރީ) ތިޔަބައިމީހުންނަށެވެ. އަދި ތިމަންމެންނީ، އެކަލާނގެއަށް އިހްލާސް ތެރި ބަޔަކީމުއެވެ.","",""],["₂ سورة البقرة","140","أَمۡ تَقُولُونَ إِنَّ إِبۡرَٰهِـۧمَ وَإِسۡمَٰعِيلَ وَإِسۡحَٰقَ وَيَعۡقُوبَ وَٱلۡأَسۡبَاطَ كَانُواْ هُودًا أَوۡ نَصَٰرَىٰۗ قُلۡ ءَأَنتُمۡ أَعۡلَمُ أَمِ ٱللَّهُۗ وَمَنۡ أَظۡلَمُ مِمَّن كَتَمَ شَهَٰدَةً عِندَهُۥ مِنَ ٱللَّهِۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا تَعۡمَلُونَ ١٤٠","أم تقولون إن إبراهيم وإسماعيل وإسحاق ويعقوب والأسباط كانوا هودا أو نصارى قل أأنتم أعلم أم الله ومن أظلم ممن كتم شهادة عنده من الله وما الله بغافل عما تعملون","އަދި ކިއެއްތަ! ހަމަކަށަވަރުން އިބްރާހީމްގެފާނާއި އިސްމާޢީލުގެފާނާއި އިސްޙާގުގެފާނާއި ޔައުގޫބުގެފާނާއި ޔައުގޫބުގެފާނުގެ އަސްބާޠުންނީ، ޔަހޫދީން ކަމުގައި ނުވަތަ ނަސާރާ އިން ކަމުގައި ވީކަމަށް ތިޔަބައިމީހުން ބުނަނީހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! (އެކަންއޮތްގޮތް) ބޮޑަށް އެނގެނީ ތިޔަބައިމީހުންނަށް ހެއްޔެވެ؟ ނުވަތަ (އެކަން ދެނެވޮޑިގަތުންބޮޑީ) ﷲ ހެއްޔެވެ؟ ﷲގެ ހަޒުރަތުން އެމީހަކަށް ލިބިފައިވާ ހެކި ވަންހަނާކޮށްފި މީހަކަށްވުރެން އަނިޔާވެރިކަންބޮޑީ ކާކުހެއްޔެވެ؟ އަދި ތިޔަބައިމީހުން ކުރާ ޢަމަލު ތަކާމެދު، ޣާފިލުވެ ވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ނުވެއެވެ.","",""],["₂ سورة البقرة","141","تِلۡكَ أُمَّةٞ قَدۡ خَلَتۡۖ لَهَا مَا كَسَبَتۡ وَلَكُم مَّا كَسَبۡتُمۡۖ وَلَا تُسۡـَٔلُونَ عَمَّا كَانُواْ يَعۡمَلُونَ ١٤١","تلك أمة قد خلت لها ما كسبت ولكم ما كسبتم ولا تسألون عما كانوا يعملون","އެއީ ހަމަކަށަވަރުން ފާއިތުވެހިނގައްޖެ އުއްމަތެކެވެ. އެ އުއްމަތް ހޯދިކަމެއް އެ އުއްމަތަށެވެ. އަދި ތިޔަބައިމީހުން ހޯދިކަމެއް ތިޔަބައިމީހުންނަށެވެ. އަދި އެއުރެން ކޮށްއުޅުނު ކަންތަކާމެދު ތިޔަބައިމީހުންނަކާ ސުވާލެއް ނުކުރައްވާހުށްޓެވެ.","",""],["₂ سورة البقرة","142","۞سَيَقُولُ ٱلسُّفَهَآءُ مِنَ ٱلنَّاسِ مَا وَلَّىٰهُمۡ عَن قِبۡلَتِهِمُ ٱلَّتِي كَانُواْ عَلَيۡهَاۚ قُل لِّلَّهِ ٱلۡمَشۡرِقُ وَٱلۡمَغۡرِبُۚ يَهۡدِي مَن يَشَآءُ إِلَىٰ صِرَٰطٖ مُّسۡتَقِيمٖ ١٤٢","سيقول السفهاء من الناس ما ولاهم عن قبلتهم التي كانوا عليها قل لله المشرق والمغرب يهدي من يشاء إلى صراط مستقيم","މީސްތަކުންގެ ތެރެއިން ހަމަބުއްދިނުވާ މީހުން ބުނާނެތެވެ. އެއުރެން (އެބަހީ: މުސްލިމުން) އިހު ތިބި ގިބްލަ ފިޔަވައި އެހެން ފަރާތަކަށް އަނބުރައިލީ ކޮން އެއްޗެއްހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! މަޝްރިގާއި މަޣްރިބު މިލްކުވެވޮޑިގެންވަނީ ﷲއަށެވެ. އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ސީދާވެގެންވާ ތެދުމަގަށް މަގުދައްކަވަތެވެ.","",""],["₂ سورة البقرة","143","وَكَذَٰلِكَ جَعَلۡنَٰكُمۡ أُمَّةٗ وَسَطٗا لِّتَكُونُواْ شُهَدَآءَ عَلَى ٱلنَّاسِ وَيَكُونَ ٱلرَّسُولُ عَلَيۡكُمۡ شَهِيدٗاۗ وَمَا جَعَلۡنَا ٱلۡقِبۡلَةَ ٱلَّتِي كُنتَ عَلَيۡهَآ إِلَّا لِنَعۡلَمَ مَن يَتَّبِعُ ٱلرَّسُولَ مِمَّن يَنقَلِبُ عَلَىٰ عَقِبَيۡهِۚ وَإِن كَانَتۡ لَكَبِيرَةً إِلَّا عَلَى ٱلَّذِينَ هَدَى ٱللَّهُۗ وَمَا كَانَ ٱللَّهُ لِيُضِيعَ إِيمَٰنَكُمۡۚ إِنَّ ٱللَّهَ بِٱلنَّاسِ لَرَءُوفٞ رَّحِيمٞ ١٤٣","وكذلك جعلناكم أمة وسطا لتكونوا شهداء على الناس ويكون الرسول عليكم شهيدا وما جعلنا القبلة التي كنت عليها إلا لنعلم من يتبع الرسول ممن ينقلب على عقبيه وإن كانت لكبيرة إلا على الذين هدى الله وما كان الله ليضيع إيمانكم إن الله بالناس لرءوف رحيم","އަދި ހަމަ އެފަދައިން، މެދުމިން އުއްމަތެއް ކަމުގައި ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން ލެއްވީމެވެ. އެއީ (ގިޔާމަތް ދުވަހުން) މީސްތަކުންގެ މައްޗަށް ހެކިވާ ބަޔަކު ކަމުގައި ތިޔަބައިމީހުން ވުމަށްޓަކައެވެ. އަދި ތިޔަބައިމީހުންގެ މައްޗަށް ހެކިވެރިޔަކު ކަމުގައި ރަސޫލާ ވެވަޑައިގަތުމަށްޓަކައެވެ. އެއުރެންތިބި ފަރާތްނޫން އަނެއްފަރާތަށް އެނބުރިގަންނަ މީހުންނާއި (އެބަހީ: ދީނުން ބޭރުވެ މުރުތައްދުވާ މީހުންނާއި) ރަސޫލާއަށް ތަބާވާ މީހުން، ތިމަންރަސްކަލާނގެ ހާމަކުރެއްވުމަށްޓަކައި މެނުވީ، އެ ގިބްލެއްގެ މަތީގައި ކަލޭގެފާނު އިހު ހުންނެވި ގިބްލަ، ގިބްލެއް ކަމުގައި ތިމަންރަސްކަލާނގެ ނުލައްވަމެވެ. ﷲ ތެދުމަގު ދެއްކެވި ބަޔަކަށްމެނުވީ، އެކަންތައް އެއީ ކަށަވަރުންވެސް ބޮޑުވެގެންވާ ކަމެކެވެ. އަދި ތިޔަބައިމީހުންގެ އީމާން ކަން ގެއްލެނި ކުރައްވާކަށެއް ﷲ ވޮޑިގެނެއް ނުވެއެވެ. ހަމަކަށަވަރުން، ﷲއީ މީސްތަކުންނަށް ނުހަނު އޯގާވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["₂ سورة البقرة","144","قَدۡ نَرَىٰ تَقَلُّبَ وَجۡهِكَ فِي ٱلسَّمَآءِۖ فَلَنُوَلِّيَنَّكَ قِبۡلَةٗ تَرۡضَىٰهَاۚ فَوَلِّ وَجۡهَكَ شَطۡرَ ٱلۡمَسۡجِدِ ٱلۡحَرَامِۚ وَحَيۡثُ مَا كُنتُمۡ فَوَلُّواْ وُجُوهَكُمۡ شَطۡرَهُۥۗ وَإِنَّ ٱلَّذِينَ أُوتُواْ ٱلۡكِتَٰبَ لَيَعۡلَمُونَ أَنَّهُ ٱلۡحَقُّ مِن رَّبِّهِمۡۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا يَعۡمَلُونَ ١٤٤","قد نرى تقلب وجهك في السماء فلنولينك قبلة ترضاها فول وجهك شطر المسجد الحرام وحيث ما كنتم فولوا وجوهكم شطره وإن الذين أوتوا الكتاب ليعلمون أنه الحق من ربهم وما الله بغافل عما يعملون","އުޑާދިމާއަށް މަތިބައްލަވައިގެން ހުންނަވައި، ކަލޭގެފާނުގެ މޫނުފުޅު އެފުށްމިފުށަށް އަނބުރުއްވާތަން ތިމަންރަސްކަލާނގެ ހަމަކަށަވަރުން ދެކެވޮޑިގެންވަމެވެ. ފަހެ، ކަލޭގެފާނު ރުހިވޮޑިގަންނަވާނޭ ގިބްލަކަށް ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ކުރިމަތިކުރައްވާ ހުށީމެވެ. ފަހެ، ހުރުމަތް ތެރިވެގެންވާ މިސްކިތާ (އެބަހީ: ކައުބަތުﷲގެފުޅާ) ދިމާއަށް، ކަލޭގެފާނުގެ މޫނުފުޅު ކުރިމަތި ކުރައްވާށެވެ! އަދި ތިޔަބައިމީހުންތިބި ކޮންމެ ތަނެއްގައިމެ، އެފަރާތަށް ތިޔަބައިމީހުންގެ މޫނުތައް ކުރިމަތިކުރާށެވެ! އަދި ހަމަކަށަވަރުން އެއީ (އެބަހީ: ގިބްލާމެދު ބާވައިލެއްވި މި ބާވައިލެއްވުމަކީ) އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އެންގެވި ހައްގު ގޮތްކަން ފޮތް ލިބުނު މީހުން ދަންނާނެކަން ކަށަވަރެވެ. އަދި އެއުރެންކުރާ ޢަމަލު ތަކާމެދު، ޣާފިލު ވެވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ނުވެއެވެ.","",""],["₂ سورة البقرة","145","وَلَئِنۡ أَتَيۡتَ ٱلَّذِينَ أُوتُواْ ٱلۡكِتَٰبَ بِكُلِّ ءَايَةٖ مَّا تَبِعُواْ قِبۡلَتَكَۚ وَمَآ أَنتَ بِتَابِعٖ قِبۡلَتَهُمۡۚ وَمَا بَعۡضُهُم بِتَابِعٖ قِبۡلَةَ بَعۡضٖۚ وَلَئِنِ ٱتَّبَعۡتَ أَهۡوَآءَهُم مِّنۢ بَعۡدِ مَا جَآءَكَ مِنَ ٱلۡعِلۡمِ إِنَّكَ إِذٗا لَّمِنَ ٱلظَّـٰلِمِينَ ١٤٥","ولئن أتيت الذين أوتوا الكتاب بكل آية ما تبعوا قبلتك وما أنت بتابع قبلتهم وما بعضهم بتابع قبلة بعض ولئن اتبعت أهواءهم من بعد ما جاءك من العلم إنك إذا لمن الظالمين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، އެއުރެންނަށް ފޮތް ދެއްވި މީހުންނަށް ހުރިހާ ބާވަތެއްގެ ހެތްކެއް ކަލޭގެފާނު ގެނެސްދެއްވިޔަސް ކަލޭގެފާނުގެ ގިބްލަކަށް އެއުރެން ތަބައެއް ނުވީހެވެ. އަދި އެއުރެންގެ ގިބްލަށް ތަބާވާ ބޭކަލަކުކަމުގައި ކަލޭގެފާނުވެސް ވެވަޑައިގެން ނުވަމުއެވެ. އަދި އެއުރެންގެ ތެރެއިން އެއްބަޔެއްގެ ގިބްލަށް ތަބާވާނޭ ބަޔަކުކަމުގައި އެއުރެންގެ އަނެއްބަޔަކު ނުވެއެވެ. އަދި ކަލޭގެފާނުގެ އަރިހަށް އިލްމުގެ ތެރެއިން އައި ކަންތަކަށްފަހު އެއުރެންގެ އެދުންތަކަށް ކަލޭގެފާނު ތަބާ ވެވަޑައިގެންފިނަމަ، ހަމަކަށަވަރުން ކަލޭގެފާނު ވެވަޑައިގަންނަވާހުށީ އަނިޔާވެރިންގެ ތެރެއިންކަން ކަށަވަރެވެ.","",""],["₂ سورة البقرة","146","ٱلَّذِينَ ءَاتَيۡنَٰهُمُ ٱلۡكِتَٰبَ يَعۡرِفُونَهُۥ كَمَا يَعۡرِفُونَ أَبۡنَآءَهُمۡۖ وَإِنَّ فَرِيقٗا مِّنۡهُمۡ لَيَكۡتُمُونَ ٱلۡحَقَّ وَهُمۡ يَعۡلَمُونَ ١٤٦","الذين آتيناهم الكتاب يعرفونه كما يعرفون أبناءهم وإن فريقا منهم ليكتمون الحق وهم يعلمون","ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ފޮތް ދެއްވި މީހުން އެއުރެންގެ އުފަންދަރިން ދަންނަ ފަދައިން އެކަލޭގެފާނު (އެބަހީ: މުޙައްމަދުގެފާނު) ދަންނާނެތެވެ. އަދި އޭގެތެރެއިން ބަޔަކު ދެނެތިބެގެންމެ، ހައްގު ވަންހަނާކުރާކަން ކަށަވަރެވެ.","",""],["₂ سورة البقرة","147","ٱلۡحَقُّ مِن رَّبِّكَ فَلَا تَكُونَنَّ مِنَ ٱلۡمُمۡتَرِينَ ١٤٧","الحق من ربك فلا تكونن من الممترين","(އެއީ) ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތު ންވާ ހައްގު ތެދުބަސްފުޅެވެ. ފަހެ، ޝައްކުކުރާ މީހުންގެ ތެރެއިން ކަލޭގެފާނު ވެވަޑައިނުގަންނަވާށެވެ!","",""],["₂ سورة البقرة","148","وَلِكُلّٖ وِجۡهَةٌ هُوَ مُوَلِّيهَاۖ فَٱسۡتَبِقُواْ ٱلۡخَيۡرَٰتِۚ أَيۡنَ مَا تَكُونُواْ يَأۡتِ بِكُمُ ٱللَّهُ جَمِيعًاۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٞ ١٤٨","ولكل وجهة هو موليها فاستبقوا الخيرات أين ما تكونوا يأت بكم الله جميعا إن الله على كل شيء قدير","ކޮންމެ މީހަކަށްމެ (އަޅުކަންކުރުމުގައި) އެމީހަކު ކުރިމަތިލާ ފަރާތެއްވެއެވެ. ފަހެ، ހެޔޮކަންތައްކޮށް އުޅުމުގައި ތިޔަބައިމީހުން އެކަކު އަނެކަކާ ވާދަކޮށް، (އެކަކު އަނެކަކަށްވުރެ) ކުރިއަރައިދާށެވެ! ތިޔަބައިމީހުން ކޮންމެ ތަނެއްގައި ތިބިކަމުގައިވިޔަސް (ގިޔާމަތް ދުވަހުން) ﷲ ތިޔަބައިމީހުން އެންމެން އެއްތާކަށް ގެންނަވާނެތެވެ. ހަމަކަށަވަރުން، ﷲއީ ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","149","وَمِنۡ حَيۡثُ خَرَجۡتَ فَوَلِّ وَجۡهَكَ شَطۡرَ ٱلۡمَسۡجِدِ ٱلۡحَرَامِۖ وَإِنَّهُۥ لَلۡحَقُّ مِن رَّبِّكَۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا تَعۡمَلُونَ ١٤٩","ومن حيث خرجت فول وجهك شطر المسجد الحرام وإنه للحق من ربك وما الله بغافل عما تعملون","އަދި ކަލޭގެފާނު (ދަތުރުފުޅަކަށް) ނުކުމެވަޑައިގަތް ކޮންމެ ތަނަކުންވިޔަސް (ނަމާދު ކުރައްވާއިރު) ހުރުމަތް ތެރިވެގެންވާ މިސްކިތާ ދިމާޔަށް ކަލޭގެފާނުގެ މޫނުފުޅު ކުރިމަތިކުރައްވާށެވެ! ހަމަކަށަވަރުން، އެއީ ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައިސްފައިވާ ހައްގު ގޮތްކަން ކަށަވަރެވެ. އަދި ތިޔަބައިމީހުން ކުރާ ޢަމަލު ތަކާމެދު ޣާފިލު ވެވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ނުވެއެވެ.","",""],["₂ سورة البقرة","150","وَمِنۡ حَيۡثُ خَرَجۡتَ فَوَلِّ وَجۡهَكَ شَطۡرَ ٱلۡمَسۡجِدِ ٱلۡحَرَامِۚ وَحَيۡثُ مَا كُنتُمۡ فَوَلُّواْ وُجُوهَكُمۡ شَطۡرَهُۥ لِئَلَّا يَكُونَ لِلنَّاسِ عَلَيۡكُمۡ حُجَّةٌ إِلَّا ٱلَّذِينَ ظَلَمُواْ مِنۡهُمۡ فَلَا تَخۡشَوۡهُمۡ وَٱخۡشَوۡنِي وَلِأُتِمَّ نِعۡمَتِي عَلَيۡكُمۡ وَلَعَلَّكُمۡ تَهۡتَدُونَ ١٥٠","ومن حيث خرجت فول وجهك شطر المسجد الحرام وحيث ما كنتم فولوا وجوهكم شطره لئلا يكون للناس عليكم حجة إلا الذين ظلموا منهم فلا تخشوهم واخشوني ولأتم نعمتي عليكم ولعلكم تهتدون","އަދި ކަލޭގެފާނު (ދަތުރުފުޅަކަށް) ނުކުމެވަޑައިގަތް ކޮންމެ ތަނަކުންވިޔަސް (ނަމާދުކުރައްވާއިރު) ހުރުމަތް ތެރިވެގެންވާ މިސްކިތާ ދިމާޔަށް ކަލޭގެފާނުގެ މޫނުފުޅު ކުރިމަތި ކުރައްވާށެވެ! އަދި ތިޔަބައިމީހުން ތިބި ކޮންމެ ތަނެއްގައިމެ، އެތަނާ ދިމާޔަށް ތިޔަބައިމީހުންގެ މޫނުތައް ކުރިމަތިކުރާށެވެ! އެއީ، އެއުރެންގެ ތެރެއިން އަނިޔާވެރިވި މީހުން ފިޔަވައި އެހެންމީހުންނަށް ތިޔަބައިމީހުންގެ މައްޗަށް ދައްކާނޭ ހުއްޖަތެއް ނެތުމަށްޓަކައެވެ. ފަހެ، ތިޔަބައިމީހުން އެއުރެންދެކެ ބިރު ނުގަންނާށެވެ! އަދި ތިމަންރަސްކަލާނގެއަށް ތިޔަބައިމީހުން ބިރުވެތިވާށެވެ! އަދި (ތިޔަބައިމީހުންނަށް ގިބްލަ އަންގައިދެއްވީ) ތިޔަބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ ދެއްވާފައިވާ ނިއުމަތް ފުރިހަމަ ކުރެއްވުމަށްޓަކައެވެ. އަދި ތިޔަބައިމީހުން ތެދުމަގު ލިބިގަތުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","151","كَمَآ أَرۡسَلۡنَا فِيكُمۡ رَسُولٗا مِّنكُمۡ يَتۡلُواْ عَلَيۡكُمۡ ءَايَٰتِنَا وَيُزَكِّيكُمۡ وَيُعَلِّمُكُمُ ٱلۡكِتَٰبَ وَٱلۡحِكۡمَةَ وَيُعَلِّمُكُم مَّا لَمۡ تَكُونُواْ تَعۡلَمُونَ ١٥١","كما أرسلنا فيكم رسولا منكم يتلو عليكم آياتنا ويزكيكم ويعلمكم الكتاب والحكمة ويعلمكم ما لم تكونوا تعلمون","ހަމައެފަދައިން ތިމަންރަސްކަލާނގެ އާޔަތްތައް ތިޔަބައިމީހުންނަށް ކިޔަވައިދެއްވައި، ތިޔަބައިމީހުން (ކުށްތަކުން) ތާހިރުކުރައްވައި، ފޮތާއި ހިކުމަތް ތިޔަބައިމީހުންނަށް އުނގަންނައިދެއްވައި، ތިޔަބައިމީހުންނަށް ކުރިން އެނގިފައިނުވާ ކަންތައް އުނގަންނައި ދެއްވުމަށްޓަކައި، ތިޔަބައިމީހުންގެ ތެރެޔަށް، ތިޔަބައިމީހުންގެ ތެރެއިން ރަސޫލަކު ތިމަންރަސްކަލާނގެ ފޮނުއްވީމެވެ.","",""],["₂ سورة البقرة","152","فَٱذۡكُرُونِيٓ أَذۡكُرۡكُمۡ وَٱشۡكُرُواْ لِي وَلَا تَكۡفُرُونِ ١٥٢","فاذكروني أذكركم واشكروا لي ولا تكفرون","ފަހެ، ތިޔަބައިމީހުން ތިމަންރަސްކަލާނގެ ހަނދުމަ ކުރާށެވެ! އޭރުން ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން ހަނދުމަކުރައްވާ ހުށީމެވެ. އަދި ތިމަންރަސްކަލާނގެއަށް ތިޔަބައިމީހުން ޝުކުރުކުރާށެވެ! އަދި ތިމަންރަސްކަލާނގެއަށް ތިޔަބައިމީހުން ކާފިރު ނުވާށެވެ!","",""],["₂ سورة البقرة","153","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ ٱسۡتَعِينُواْ بِٱلصَّبۡرِ وَٱلصَّلَوٰةِۚ إِنَّ ٱللَّهَ مَعَ ٱلصَّـٰبِرِينَ ١٥٣","يا أيها الذين آمنوا استعينوا بالصبر والصلاة إن الله مع الصابرين","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ކެތްތެރިކަމާއި ނަމާދުން ތިޔަބައިމީހުން ވާގި އެދޭށެވެ! ހަމަކަށަވަރުން ﷲ ވޮޑިގެންވަނީ ކެތްތެރިންނާ އެކުގައެވެ.","",""],["₂ سورة البقرة","154","وَلَا تَقُولُواْ لِمَن يُقۡتَلُ فِي سَبِيلِ ٱللَّهِ أَمۡوَٰتُۢۚ بَلۡ أَحۡيَآءٞ وَلَٰكِن لَّا تَشۡعُرُونَ ١٥٤","ولا تقولوا لمن يقتل في سبيل الله أموات بل أحياء ولكن لا تشعرون","އަދި ﷲގެ މަގުގައި (ޖިހާދުކުރަނިކޮށް) ޝަހީދުވާ މީހުންނާމެދު (އެއީ) މަރުވެފައިވާ ބަޔެކޭ، ތިޔަބައިމީހުން ނުބުނާށެވެ! އަދި ކިއެއްތަ! އެއުރެންނީ، ދިރިތިބި ބަޔެކެވެ. އެހެނެއްކަމަކު (އެކަން) ތިޔަބައިމީހުންނަށް ނޭނގެނީއެވެ.","",""],["₂ سورة البقرة","155","وَلَنَبۡلُوَنَّكُم بِشَيۡءٖ مِّنَ ٱلۡخَوۡفِ وَٱلۡجُوعِ وَنَقۡصٖ مِّنَ ٱلۡأَمۡوَٰلِ وَٱلۡأَنفُسِ وَٱلثَّمَرَٰتِۗ وَبَشِّرِ ٱلصَّـٰبِرِينَ ١٥٥","ولنبلونكم بشيء من الخوف والجوع ونقص من الأموال والأنفس والثمرات وبشر الصابرين","ހަމަކަށަވަރުން ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން އިމްތިހާނުކުރައްވާހުށީމެވެ. (އެއީ) ބިރުވެރިކަމާއި ބަނޑުހައިހޫނުކަމުގެ ތެރެއިން ކަމެއް މެދުވެރިކުރެއްވުމުންނެވެ. އަދި މުދާތަކާއި ފުރާނަތަކާއި މޭވާތައް އުނިކުރެއްވުމުންނެވެ. އަދި ކެތްތެރިންނަށް އުފާވެރިކަމުގެ ޚަބަރު، ކަލޭގެފާނު ދެއްވާށެވެ!","",""],["₂ سورة البقرة","156","ٱلَّذِينَ إِذَآ أَصَٰبَتۡهُم مُّصِيبَةٞ قَالُوٓاْ إِنَّا لِلَّهِ وَإِنَّآ إِلَيۡهِ رَٰجِعُونَ ١٥٦","الذين إذا أصابتهم مصيبة قالوا إنا لله وإنا إليه راجعون","އެއުރެންނީ އެއުރެންނަށް މުސީބަތެއް ޖެހިއްޖެނަމަ، ހަމަކަށަވަރުން ތިމަންމެންނީ، ﷲއަށް މިލްކުވެވޮޑިގެންވާ ބަޔެކޭ، އަދި ހަމަކަށަވަރުން ތިމަންމެންނީ، އެކަލާނގެ ހަޒުރަތަށް އެނބުރިދާނޭ ބަޔެކޭ ބުނާ މީހުންނެވެ.","",""],["₂ سورة البقرة","157","أُوْلَـٰٓئِكَ عَلَيۡهِمۡ صَلَوَٰتٞ مِّن رَّبِّهِمۡ وَرَحۡمَةٞۖ وَأُوْلَـٰٓئِكَ هُمُ ٱلۡمُهۡتَدُونَ ١٥٧","أولئك عليهم صلوات من ربهم ورحمة وأولئك هم المهتدون","އެއުރެންނީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން މަޣުފިރަތާއި ރަހުމަތެއުރެންގެ މައްޗަށް ހުރި މީހުންނެވެ. އަދި ތެދުމަގު ލިބިގެންވާ މީހުންނީ ހަމަ އެއުރެންނެވެ.","",""],["₂ سورة البقرة","158","۞إِنَّ ٱلصَّفَا وَٱلۡمَرۡوَةَ مِن شَعَآئِرِ ٱللَّهِۖ فَمَنۡ حَجَّ ٱلۡبَيۡتَ أَوِ ٱعۡتَمَرَ فَلَا جُنَاحَ عَلَيۡهِ أَن يَطَّوَّفَ بِهِمَاۚ وَمَن تَطَوَّعَ خَيۡرٗا فَإِنَّ ٱللَّهَ شَاكِرٌ عَلِيمٌ ١٥٨","إن الصفا والمروة من شعائر الله فمن حج البيت أو اعتمر فلا جناح عليه أن يطوف بهما ومن تطوع خيرا فإن الله شاكر عليم","ހަމަކަށަވަރުން، ޞަފާއާއި މަރްވާ ވަނީ ﷲގެ ޝަޢާއިރު (އެބަހީ: ފާޅުގައި އަޅުކަން ކުރުމަށް ލައްވާފައިވާ ތަންތަން) ގެ ތެރެއިންނެވެ. ފަހެ، ގެފުޅަށްގޮސް ހައްޖުވާ މީހާ ނުވަތަ އުމްރާވާ މީހާ، އެ ދެތާނގައި ހިނގައި ސައުޔުކުރުމަކުން އެމީހާގެ މައްޗަކަށް ކުށެއްނެތެވެ. އަދި (ފަރުޟުގެ އިތުރަށް) ހެޔޮކަމެއްކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން ﷲއީ، (އެފަދަ މީހުންނަށް) ޝުކުރުވެރިވެވޮޑިގެންވާ (އެބަހީ: އެއުރެންނަށް ހެޔޮ ޖަޒާދެއްވާ) މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","159","إِنَّ ٱلَّذِينَ يَكۡتُمُونَ مَآ أَنزَلۡنَا مِنَ ٱلۡبَيِّنَٰتِ وَٱلۡهُدَىٰ مِنۢ بَعۡدِ مَا بَيَّنَّـٰهُ لِلنَّاسِ فِي ٱلۡكِتَٰبِ أُوْلَـٰٓئِكَ يَلۡعَنُهُمُ ٱللَّهُ وَيَلۡعَنُهُمُ ٱللَّـٰعِنُونَ ١٥٩","إن الذين يكتمون ما أنزلنا من البينات والهدى من بعد ما بيناه للناس في الكتاب أولئك يلعنهم الله ويلعنهم اللاعنون","ހަމަކަށަވަރުން ބަޔާންވެގެންވާ ހެކިތަކާއި ތެދުމަގުގެ ތެރެއިން ތިމަންރަސްކަލާނގެ ބާވައިލެއްވި ތަކެތި މީސްތަކުންނަށް ތިމަންރަސްކަލާނގެ އެފޮތުގައި ބަޔާންކޮށް ދެއްވުމަށްފަހު، އެތަކެތި ވަންހަނާކުރާ މީހުން (ދަންނާށެވެ!) އެއުރެންނަށް ﷲ، ލައުނަތް ލައްވާނެތެވެ. އަދި ލައުނަތް ދޭ މީހުންވެސް އެއުރެންނަށް ލައުނަތް ދޭނެތެވެ.","",""],["₂ سورة البقرة","160","إِلَّا ٱلَّذِينَ تَابُواْ وَأَصۡلَحُواْ وَبَيَّنُواْ فَأُوْلَـٰٓئِكَ أَتُوبُ عَلَيۡهِمۡ وَأَنَا ٱلتَّوَّابُ ٱلرَّحِيمُ ١٦٠","إلا الذين تابوا وأصلحوا وبينوا فأولئك أتوب عليهم وأنا التواب الرحيم","އެއުރެން ތައުބާވެ (އެއުރެންގެ ޢަމަލުތައް) އިސްލާހު ކޮށް (ވަންހަނާކުރި ކަންތައް) ބަޔާންކުޅަ މީހުން މެނުވީއެވެ. ފަހެ، އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ތައުބާ ލައްވާހުށީމެވެ. ތިމަންރަސްކަލާނގެއީ، ގިނަގިނައިން ތައުބާ ގަބޫލުކުރައްވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","161","إِنَّ ٱلَّذِينَ كَفَرُواْ وَمَاتُواْ وَهُمۡ كُفَّارٌ أُوْلَـٰٓئِكَ عَلَيۡهِمۡ لَعۡنَةُ ٱللَّهِ وَٱلۡمَلَـٰٓئِكَةِ وَٱلنَّاسِ أَجۡمَعِينَ ١٦١","إن الذين كفروا وماتوا وهم كفار أولئك عليهم لعنة الله والملائكة والناس أجمعين","ހަމަކަށަވަރުން ކާފިރުވެ އަދި ކާފިރުން ކަމުގައިތިބެ މަރުވި މީހުން (ދަންނާށެވެ!) އެއުރެންގެ މައްޗަށް ﷲއާއި މަލާއިކަތްނާއި އެންމެހާ މީސްތަކުންގެ ލައުނަތް ހުށްޓެވެ.","",""],["₂ سورة البقرة","162","خَٰلِدِينَ فِيهَا لَا يُخَفَّفُ عَنۡهُمُ ٱلۡعَذَابُ وَلَا هُمۡ يُنظَرُونَ ١٦٢","خالدين فيها لا يخفف عنهم العذاب ولا هم ينظرون","އެއުރެން އެ ލައުނަތުގައި ދެމިތިބެނިވި ގޮތުގައެވެ. އެއުރެންގެ ކިބަޔަކުން އަޒާބެއް ލުޔެއް ނުކުރައްވާނެތެވެ. އަދި އެއުރެންނަށް (އަޒާބު ލިބުމުގައި) ލަހެއްވެސް ނުމެކުރައްވާނެތެވެ.","",""],["₂ سورة البقرة","163","وَإِلَٰهُكُمۡ إِلَٰهٞ وَٰحِدٞۖ لَّآ إِلَٰهَ إِلَّا هُوَ ٱلرَّحۡمَٰنُ ٱلرَّحِيمُ ١٦٣","وإلهكم إله واحد لا إله إلا هو الرحمن الرحيم","އަދި ތިޔަބައިމީހުންގެ ކަލާނގެއީ، އެއްކައުވަންތަ ރަސްކަލާނގެއެވެ. އެކަލާނގެ މެނުވީ އިލާހަކު ނުވެއެވެ. އެއީ ރަޙްމާންވަންތަ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","164","إِنَّ فِي خَلۡقِ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ وَٱخۡتِلَٰفِ ٱلَّيۡلِ وَٱلنَّهَارِ وَٱلۡفُلۡكِ ٱلَّتِي تَجۡرِي فِي ٱلۡبَحۡرِ بِمَا يَنفَعُ ٱلنَّاسَ وَمَآ أَنزَلَ ٱللَّهُ مِنَ ٱلسَّمَآءِ مِن مَّآءٖ فَأَحۡيَا بِهِ ٱلۡأَرۡضَ بَعۡدَ مَوۡتِهَا وَبَثَّ فِيهَا مِن كُلِّ دَآبَّةٖ وَتَصۡرِيفِ ٱلرِّيَٰحِ وَٱلسَّحَابِ ٱلۡمُسَخَّرِ بَيۡنَ ٱلسَّمَآءِ وَٱلۡأَرۡضِ لَأٓيَٰتٖ لِّقَوۡمٖ يَعۡقِلُونَ ١٦٤","إن في خلق السماوات والأرض واختلاف الليل والنهار والفلك التي تجري في البحر بما ينفع الناس وما أنزل الله من السماء من ماء فأحيا به الأرض بعد موتها وبث فيها من كل دابة وتصريف الرياح والسحاب المسخر بين السماء والأرض لآيات لقوم يعقلون","ހަމަކަށަވަރުން އުޑުތަކާއި ބިން ހެއްދެވުމުގައްޔާއި، ރޭދުވާ ތަފާތު ވުމުގައްޔާއި، މީސްތަކުންނަށް މަންފާކުރާ ތަކެއްޗާއިގެން ކަނޑުމަތީގައި ދުވާ އުޅަނދުތަކުގައްޔާއި، ﷲ އުޑުން ވެއްސެވި ފެނުގައްޔާއި، ފަހެ، ބިން މަރުވެ އޮތުމަށްފަހު އެފެނުގެ ސަބަބުން ބިމަށް ދިރުން ދެއްވައިފުމާއި، އަދި ހިނގައިބިނގައިއުޅޭ އެންމެހާ ބާވަތްތަކުގެ ދިރޭތަކެތި، އެ ބިމުގައި ފަތުރުއްވައިފުމާއި، އަދި އެކި ފަރާތްފަރާތުން ޖެހޭގޮތުގައި ވައިޖެއްސެވުމުގައްޔާއި، އުޑާއި ބިމާ ދެމެދު ކިޔަމަންކުރައްވާފައިވާ ވިލާގައި، ވިސްނާބަޔަކަށް ކަނޑައެޅިގެންހުރި ހެކިތަކެއް ވާކަން ކަށަވަރެވެ.","",""],["₂ سورة البقرة","165","وَمِنَ ٱلنَّاسِ مَن يَتَّخِذُ مِن دُونِ ٱللَّهِ أَندَادٗا يُحِبُّونَهُمۡ كَحُبِّ ٱللَّهِۖ وَٱلَّذِينَ ءَامَنُوٓاْ أَشَدُّ حُبّٗا لِّلَّهِۗ وَلَوۡ يَرَى ٱلَّذِينَ ظَلَمُوٓاْ إِذۡ يَرَوۡنَ ٱلۡعَذَابَ أَنَّ ٱلۡقُوَّةَ لِلَّهِ جَمِيعٗا وَأَنَّ ٱللَّهَ شَدِيدُ ٱلۡعَذَابِ ١٦٥","ومن الناس من يتخذ من دون الله أندادا يحبونهم كحب الله والذين آمنوا أشد حبا لله ولو يرى الذين ظلموا إذ يرون العذاب أن القوة لله جميعا وأن الله شديد العذاب","އަދި ﷲ ފިޔަވައި އެކަލާނގެއާ އެއްފަދަ ޝަރީކުން ތަކެއް ބަލައިގަންނަ ބަޔަކު، މީސްތަކުންގެ ތެރެއިންވެއެވެ. ﷲ ދެކެ ލޯބިވާ ފަދައިން، އެއުރެން އެ ޝަރީކުން ދެކެ ލޯބިވެތެވެ. އަދި އީމާންވި މީހުން ﷲ ދެކެ ލޯބިވުން މާބޮޑެވެ. އަދި އަނިޔާވެރިވި މީހުންނަށް (އާޚިރަތް ދުވަހުގެ) އަޒާބު ފެންނަހިނދު، ހަމަކަށަވަރުން އެންމެހާ ބާރުތައް މިލްކުވެވޮޑިގެންވަނީ ﷲއަށް ކަމާއި އަދި ހަމަކަށަވަރުން ﷲއީ އަޒާބު ދެއްވުމުގައި ގަދަފަދަވެވޮޑިގެންވާ ރަސްކަލާނގެކަން އެއުރެންނަށް އެނގޭނެ ނަމައެވެ.","",""],["₂ سورة البقرة","166","إِذۡ تَبَرَّأَ ٱلَّذِينَ ٱتُّبِعُواْ مِنَ ٱلَّذِينَ ٱتَّبَعُواْ وَرَأَوُاْ ٱلۡعَذَابَ وَتَقَطَّعَتۡ بِهِمُ ٱلۡأَسۡبَابُ ١٦٦","إذ تبرأ الذين اتبعوا من الذين اتبعوا ورأوا العذاب وتقطعت بهم الأسباب","އެއީ ތަބާ ވެވުނުމީހުން ތަބާ ވިމީހުންގެ ކިބައިން ދުރުހެލިވެ ބަރީއަވެގަންނަ ހިނދެވެ. އަދި އެއުރެން (އެބަހީ: އެ ދެބައިމީހުން) އަޒާބު ދެކޭހިނދެވެ. އަދި އެއުރެންގެ މެދުގައިވާ ގުޅުންތަކުގެ ސަބަބުތައް ކެނޑިގެންދާ ހިނދެވެ.","",""],["₂ سورة البقرة","167","وَقَالَ ٱلَّذِينَ ٱتَّبَعُواْ لَوۡ أَنَّ لَنَا كَرَّةٗ فَنَتَبَرَّأَ مِنۡهُمۡ كَمَا تَبَرَّءُواْ مِنَّاۗ كَذَٰلِكَ يُرِيهِمُ ٱللَّهُ أَعۡمَٰلَهُمۡ حَسَرَٰتٍ عَلَيۡهِمۡۖ وَمَا هُم بِخَٰرِجِينَ مِنَ ٱلنَّارِ ١٦٧","وقال الذين اتبعوا لو أن لنا كرة فنتبرأ منهم كما تبرءوا منا كذلك يريهم الله أعمالهم حسرات عليهم وما هم بخارجين من النار","އަދި ތަބާ ވިމީހުން ބުނޫއެވެ. ތިމަންމެންނަށް އަލުން ދުނިޔެއަށް އަދި އެއްފަހަރު އެނބުރި ދިޔުމެއް ލިބޭނެ ނަމައެވެ. (އެއީ) ތިމަންމެންގެ ކިބައިން ބަރީއަވެގަތް ފަދައިން، ތިމަންމެންވެސް އެއުރެންގެ ކިބައިން ބަރީއަވެގަތުމަށެވެ. އެއުރެންގެ ޢަމަލު ތަކަކީ، އެއުރެންގެ މައްޗަށްވާ ހިތާމަތަކެއް ކަމުގައި ﷲއެއުރެންނަށް ދައްކަވަނީ އެފަދައިންނެވެ. އަދި ނަރަކައިގެ ތެރެއިން ނުކުންނާނޭ ބަޔަކު ކަމުގައި އެއުރެން ނުވެތެވެ.","",""],["₂ سورة البقرة","168","يَـٰٓأَيُّهَا ٱلنَّاسُ كُلُواْ مِمَّا فِي ٱلۡأَرۡضِ حَلَٰلٗا طَيِّبٗا وَلَا تَتَّبِعُواْ خُطُوَٰتِ ٱلشَّيۡطَٰنِۚ إِنَّهُۥ لَكُمۡ عَدُوّٞ مُّبِينٌ ١٦٨","يا أيها الناس كلوا مما في الأرض حلالا طيبا ولا تتبعوا خطوات الشيطان إنه لكم عدو مبين","އޭ މީސްތަކުންނޭވެ! ބިމުގައިވާ ތަކެތީގެ ތެރެއިން ހަލާލު ރަނގަޅު ތަކެތި ތިޔަބައިމީހުން ކައިއުޅޭށެވެ! އަދި ޝައިތާނާގެ ފިޔަވަޅުތަކަށް ތިޔަބައިމީހުން ތަބާ ނުވާށެވެ! (އެހެނީ) ހަމަކަށަވަރުން އެ ޝައިތާނާއީ، ތިޔަބައިމީހުންނަށްހުރި ކަނޑައެޅި ބަޔާންވެގެންވާ އަދާވަތް ތެރިޔެކެވެ.","",""],["₂ سورة البقرة","169","إِنَّمَا يَأۡمُرُكُم بِٱلسُّوٓءِ وَٱلۡفَحۡشَآءِ وَأَن تَقُولُواْ عَلَى ٱللَّهِ مَا لَا تَعۡلَمُونَ ١٦٩","إنما يأمركم بالسوء والفحشاء وأن تقولوا على الله ما لا تعلمون","އެ ޝައިތާނާ ތިޔަބައިމީހުންނަށް އަމުރުކުރާކަން ކަށަވަރީ ނުބައިކަންތަކާއި ހުތުރުކަންބޮޑު ފާފަތަކަށެވެ. އަދި ތިޔަބައިމީހުންނަށް އެނގިގެންނުވާ އެއްޗެއް ﷲއާމެދު ތިޔަބައިމީހުން ބުނުމަށެވެ.","",""],["₂ سورة البقرة","170","وَإِذَا قِيلَ لَهُمُ ٱتَّبِعُواْ مَآ أَنزَلَ ٱللَّهُ قَالُواْ بَلۡ نَتَّبِعُ مَآ أَلۡفَيۡنَا عَلَيۡهِ ءَابَآءَنَآۚ أَوَلَوۡ كَانَ ءَابَآؤُهُمۡ لَا يَعۡقِلُونَ شَيۡـٔٗا وَلَا يَهۡتَدُونَ ١٧٠","وإذا قيل لهم اتبعوا ما أنزل الله قالوا بل نتبع ما ألفينا عليه آباءنا أولو كان آباؤهم لا يعقلون شيئا ولا يهتدون","އަދި ﷲ ބާވައިލެއްވި އެއްޗަކަށް ތިޔަބައިމީހުން ތަބާ ވާށޭ އެއުރެންގެ ގާތުގައި ބުނެފިނަމަ އެއުރެން ބުނާނެތެވެ. އަދި ކީއްހެއްޔެވެ؟ ތިމަންމެން ތަބާ ވާހުށީ ތިމަންމެންގެ ކާބަފައިން އެގޮތެއްގެ މަތީގައި ތިބޭތީ ތިމަންމެންނަށް ފެނުނު ގޮތަށެވެ. ފަހެ، އެއުރެންގެ ކާބަފައިންނަށް އެއްވެސް ކަމެއް ނުވިސްނުނަސް، އަދި އެއުރެންނަށް ތެދުމަގު ނުލިބުނަސް ހެއްޔެވެ؟","",""],["₂ سورة البقرة","171","وَمَثَلُ ٱلَّذِينَ كَفَرُواْ كَمَثَلِ ٱلَّذِي يَنۡعِقُ بِمَا لَا يَسۡمَعُ إِلَّا دُعَآءٗ وَنِدَآءٗۚ صُمُّۢ بُكۡمٌ عُمۡيٞ فَهُمۡ لَا يَعۡقِلُونَ ١٧١","ومثل الذين كفروا كمثل الذي ينعق بما لا يسمع إلا دعاء ونداء صم بكم عمي فهم لا يعقلون","ކާފިރުވި މީހުން (ނަށް ދީނަށް ގޮވާލާ މީހާ) ގެ މިސާލީ (އެބަހީ: ކާފިރުންނަށް ރަސޫލާ ގޮވާލައްވާ ގޮވާލެއްވުމަށް ނިސްބަތްކޮށް ބަލާއިރު އެއުރެންނާއި ރަސޫލާގެ މިސާލީ) ގޮވުމެއް ނުވަތަ ހަޅޭއްލެވުމެއްގެ އަޑުނޫނީ ނީވޭ ޖަނަވާރަށް ގޮވާ މީހާގެ މިސާލެވެ. އެ ކާފިރުންނީ ބީރު، މަންމަން، ކަނު ބަޔެކެވެ. ފަހެ، އެއުރެންނަކަށް ނުވިސްނެއެވެ.","",""],["₂ سورة البقرة","172","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ كُلُواْ مِن طَيِّبَٰتِ مَا رَزَقۡنَٰكُمۡ وَٱشۡكُرُواْ لِلَّهِ إِن كُنتُمۡ إِيَّاهُ تَعۡبُدُونَ ١٧٢","يا أيها الذين آمنوا كلوا من طيبات ما رزقناكم واشكروا لله إن كنتم إياه تعبدون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް ދެއްވި ރަނގަޅު ތަކެތިން ތިޔަބައިމީހުން ކައިއުޅޭށެވެ! އަދި ތިޔަބައިމީހުން ހަމައެކަނި ﷲއަށް އަޅުކަންކުރާ ކަމުގައިވާނަމަ، އެކަލާނގެއަށް ޝުކުރުވެރިވާށެވެ.","",""],["₂ سورة البقرة","173","إِنَّمَا حَرَّمَ عَلَيۡكُمُ ٱلۡمَيۡتَةَ وَٱلدَّمَ وَلَحۡمَ ٱلۡخِنزِيرِ وَمَآ أُهِلَّ بِهِۦ لِغَيۡرِ ٱللَّهِۖ فَمَنِ ٱضۡطُرَّ غَيۡرَ بَاغٖ وَلَا عَادٖ فَلَآ إِثۡمَ عَلَيۡهِۚ إِنَّ ٱللَّهَ غَفُورٞ رَّحِيمٌ ١٧٣","إنما حرم عليكم الميتة والدم ولحم الخنزير وما أهل به لغير الله فمن اضطر غير باغ ولا عاد فلا إثم عليه إن الله غفور رحيم","ތިޔަބައިމީހުންނަށް އެކަލާނގެ ހަރާމްކުރައްވާފައިވާކަން ކަށަވަރީ، މުޅަ ތަކެއްޗާއި، ލެޔާއި، އޫރުމަހާއި، ﷲ ފިޔަވައި އެހެން ފަރާތެއްގެ ނަންގަނެ ކަތިލާ ތަކެއްޗެވެ. ފަހެ، މަޖުބޫރު ވެއްޖެމީހާ ނުކިޔަމަންތެރިކަމެއް އަދި ހައްދުފަހަނަޅައި ދިޔުމެއްނެތި (އެތަކެތިން ކެއުމުގައި) އެމީހާގެ މައްޗަކަށް ފާފައެއް ނެތެވެ. ހަމަކަށަވަރުން ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","174","إِنَّ ٱلَّذِينَ يَكۡتُمُونَ مَآ أَنزَلَ ٱللَّهُ مِنَ ٱلۡكِتَٰبِ وَيَشۡتَرُونَ بِهِۦ ثَمَنٗا قَلِيلًا أُوْلَـٰٓئِكَ مَا يَأۡكُلُونَ فِي بُطُونِهِمۡ إِلَّا ٱلنَّارَ وَلَا يُكَلِّمُهُمُ ٱللَّهُ يَوۡمَ ٱلۡقِيَٰمَةِ وَلَا يُزَكِّيهِمۡ وَلَهُمۡ عَذَابٌ أَلِيمٌ ١٧٤","إن الذين يكتمون ما أنزل الله من الكتاب ويشترون به ثمنا قليلا أولئك ما يأكلون في بطونهم إلا النار ولا يكلمهم الله يوم القيامة ولا يزكيهم ولهم عذاب أليم","ހަމަކަށަވަރުން ފޮތުގެ ތެރެއިން ﷲ ބާވައިލެއްވި ތަކެތި ވަންހަނާކޮށް އެ ތަކެއްޗަށް ކުޑައަގެއްގަނެ އުޅޭ މީހުން އަލިފާންނޫން އެހެން އެއްޗެއް އެއުރެންގެ ބަނޑަށް (އަޅައި) ކައި ނޫޅެތެވެ. އަދި ގިޔާމަތް ދުވަހުން ﷲއެއުރެންނަކަށް ބަސް ވަހީއެއް ނުކުރައްވާނެތެވެ. އަދި އެއުރެން ތާހިރެއްވެސް ނުކުރައްވާނެތެވެ. އަދި އެއުރެންނަށް ހުރީ ވޭންދެނިވި އަޒާބެވެ.","",""],["₂ سورة البقرة","175","أُوْلَـٰٓئِكَ ٱلَّذِينَ ٱشۡتَرَوُاْ ٱلضَّلَٰلَةَ بِٱلۡهُدَىٰ وَٱلۡعَذَابَ بِٱلۡمَغۡفِرَةِۚ فَمَآ أَصۡبَرَهُمۡ عَلَى ٱلنَّارِ ١٧٥","أولئك الذين اشتروا الضلالة بالهدى والعذاب بالمغفرة فما أصبرهم على النار","އެއުރެންނީ، ތެދުމަގުގެ ބަދަލުގައި މަގުފުރެދުން އަދި ފާފަފުއްސެވުމުގެ ބަދަލުގައި އަޒާބު ގަތް މީހުންނެވެ. ފަހެ، ނަރަކަ (އިގެ އަޒާބު) އަށް އެއުރެންނަށް ކެތްކުރެވޭނީ ކިހިނެއް ހެއްޔެވެ؟","",""],["₂ سورة البقرة","176","ذَٰلِكَ بِأَنَّ ٱللَّهَ نَزَّلَ ٱلۡكِتَٰبَ بِٱلۡحَقِّۗ وَإِنَّ ٱلَّذِينَ ٱخۡتَلَفُواْ فِي ٱلۡكِتَٰبِ لَفِي شِقَاقِۭ بَعِيدٖ ١٧٦","ذلك بأن الله نزل الكتاب بالحق وإن الذين اختلفوا في الكتاب لفي شقاق بعيد","އެއީ ހަމަކަށަވަރުން ﷲ، ހައްގު ގޮތުގައި ފޮތް ބާވައިލައްވާފައިވާ ކަމަށްޓަކައެވެ. އަދި ހަމަކަށަވަރުން ފޮތާމެދު ޚިލާފުވި މީހުންވަނީ (ހައްގާ) ދުރުވެގެންވާ ދެކޮޅުވެރި ކަމެއްގެ ތެރޭގައިކަން ކަށަވަރެވެ.","",""],["₂ سورة البقرة","177","۞لَّيۡسَ ٱلۡبِرَّ أَن تُوَلُّواْ وُجُوهَكُمۡ قِبَلَ ٱلۡمَشۡرِقِ وَٱلۡمَغۡرِبِ وَلَٰكِنَّ ٱلۡبِرَّ مَنۡ ءَامَنَ بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِ وَٱلۡمَلَـٰٓئِكَةِ وَٱلۡكِتَٰبِ وَٱلنَّبِيِّـۧنَ وَءَاتَى ٱلۡمَالَ عَلَىٰ حُبِّهِۦ ذَوِي ٱلۡقُرۡبَىٰ وَٱلۡيَتَٰمَىٰ وَٱلۡمَسَٰكِينَ وَٱبۡنَ ٱلسَّبِيلِ وَٱلسَّآئِلِينَ وَفِي ٱلرِّقَابِ وَأَقَامَ ٱلصَّلَوٰةَ وَءَاتَى ٱلزَّكَوٰةَ وَٱلۡمُوفُونَ بِعَهۡدِهِمۡ إِذَا عَٰهَدُواْۖ وَٱلصَّـٰبِرِينَ فِي ٱلۡبَأۡسَآءِ وَٱلضَّرَّآءِ وَحِينَ ٱلۡبَأۡسِۗ أُوْلَـٰٓئِكَ ٱلَّذِينَ صَدَقُواْۖ وَأُوْلَـٰٓئِكَ هُمُ ٱلۡمُتَّقُونَ ١٧٧","ليس البر أن تولوا وجوهكم قبل المشرق والمغرب ولكن البر من آمن بالله واليوم الآخر والملائكة والكتاب والنبيين وآتى المال على حبه ذوي القربى واليتامى والمساكين وابن السبيل والسائلين وفي الرقاب وأقام الصلاة وآتى الزكاة والموفون بعهدهم إذا عاهدوا والصابرين في البأساء والضراء وحين البأس أولئك الذين صدقوا وأولئك هم المتقون","ހެޔޮކަމަކީ (ހަމައެކަނި) އިރުމަތިފަރާތަށް ނުވަތަ ހުޅަނގުފަރާތަށް ތިޔަބައިމީހުންގެ މޫނުތައް ކުރިމަތި ކުރުމެއް ނޫނެވެ. އެހެނެއް ކަމަކު، ހެޔޮކަންކުރާ މީހާއީ، ﷲއަށާއި އާޚިރަތް ދުވަހަށާއި މަލާއިކަތުންނަށާއި ފޮތަށާއި ނަބިއްޔުންނަށް އީމާންވި މީހާއެވެ. އަދި މުދަލުގެ މައްޗަށް ލޯބިހުރުމާއެކުވެސް، ގާތްތިމާގެ މީހުންނަށާއި ޔަތީމުންނަށާއި މިސްކީނުންނަށާއި (ޙާލުގައި ޖެހިފައިވާ) ދަތުރުވެރިންނަށާއި އެހީޔަށްއެދި ސުވާލުކުރާ މީހުންނަށާއި އަޅުން މިނިވަންކުރުމުގައި މުދާ ހޭދަކުރި މީހާއެވެ. އަދި ނަމާދު ގާއިމު ކޮށް، ޒަކާތް ދީއުޅޭ މީހާއެވެ. އަދި އަހުދެއް ކޮށްފިނަމަ އެއުރެންގެ އަހުދު ފުއްދާ މީހުންނެވެ. އަދި ތަދުމަޑުކަމާއި ބަލިމަޑުކަމާއި ހަނގުރާމައިގެ ވަގުތުގައި ކެތްކުރާ މީހުންނެވެ. ތެދުވެރިވި މީހުންނަކީ، އެއުރެންނެވެ. އަދި ތަގުވާވެރިންނަކީވެސް ހަމަ އެއުރެންނެވެ.","",""],["₂ سورة البقرة","178","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ كُتِبَ عَلَيۡكُمُ ٱلۡقِصَاصُ فِي ٱلۡقَتۡلَىۖ ٱلۡحُرُّ بِٱلۡحُرِّ وَٱلۡعَبۡدُ بِٱلۡعَبۡدِ وَٱلۡأُنثَىٰ بِٱلۡأُنثَىٰۚ فَمَنۡ عُفِيَ لَهُۥ مِنۡ أَخِيهِ شَيۡءٞ فَٱتِّبَاعُۢ بِٱلۡمَعۡرُوفِ وَأَدَآءٌ إِلَيۡهِ بِإِحۡسَٰنٖۗ ذَٰلِكَ تَخۡفِيفٞ مِّن رَّبِّكُمۡ وَرَحۡمَةٞۗ فَمَنِ ٱعۡتَدَىٰ بَعۡدَ ذَٰلِكَ فَلَهُۥ عَذَابٌ أَلِيمٞ ١٧٨","يا أيها الذين آمنوا كتب عليكم القصاص في القتلى الحر بالحر والعبد بالعبد والأنثى بالأنثى فمن عفي له من أخيه شيء فاتباع بالمعروف وأداء إليه بإحسان ذلك تخفيف من ربكم ورحمة فمن اعتدى بعد ذلك فله عذاب أليم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ގަތުލުކުރެވޭ މީހުންނާމެދު ގިސާސް ހިފުން ތިޔަބައިމީހުންގެ މައްޗަށް ފަރުޟުކުރައްވައިފިއެވެ. މިނިވަނަކަށް މިނިވަނެކެވެ. އަޅަކަށް އަޅެކެވެ. އަންހެނަކަށް އަންހެނެކެވެ. ފަހެ، އެމީހާގެ (މަރުވި) އަޚާގެ ފަރާތުން ގިސާސްގެ ބައެއް މާފުކުރެވުނު މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާގެ ކިބައިން ހެޔޮގޮތުގައި މަރުގެ ދިޔައަށް (ވާރުތަވެރިޔާ) އެދުން ހުށްޓެވެ. އަދި އިހްސާން ތެރިކަމާއެކު މާފުކުރި ފަރާތަށް (މާފުކުރެވުނުމީހާ) އެދިޔަ އަދާކުރުން ހުށްޓެވެ. އެއީ ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން (ތިޔަބައިމީހުންނަށް) ދެއްވި ލުޔެކެވެ. އަދި ރަހުމަތެކެވެ. އެއަށްފަހު، ދެކޮޅުވެރިވެ އަދާވަތް ތެރިވެއްޖެ މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާއަށް ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["₂ سورة البقرة","179","وَلَكُمۡ فِي ٱلۡقِصَاصِ حَيَوٰةٞ يَـٰٓأُوْلِي ٱلۡأَلۡبَٰبِ لَعَلَّكُمۡ تَتَّقُونَ ١٧٩","ولكم في القصاص حياة يا أولي الألباب لعلكم تتقون","އަދި ގިސާސް ހިފުމުގައި ތިޔަބައިމީހުންނަށް (ވަރަށްބޮޑު) ދިރުމެއްވެއެވެ. އޭ ބުއްދީގެ އަހުލުވެރިންނޭވެ! (އެއީ) ތިޔަބައިމީހުން ތަގުވާވެރިވުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","180","كُتِبَ عَلَيۡكُمۡ إِذَا حَضَرَ أَحَدَكُمُ ٱلۡمَوۡتُ إِن تَرَكَ خَيۡرًا ٱلۡوَصِيَّةُ لِلۡوَٰلِدَيۡنِ وَٱلۡأَقۡرَبِينَ بِٱلۡمَعۡرُوفِۖ حَقًّا عَلَى ٱلۡمُتَّقِينَ ١٨٠","كتب عليكم إذا حضر أحدكم الموت إن ترك خيرا الوصية للوالدين والأقربين بالمعروف حقا على المتقين","ތިޔަބައިމީހުންކުރެ މީހަކުގެ ގާތަށް މަރުއައިސް ޙާޒިރުު ވާހިނދު އެމީހާ މުދަލެއް ދޫކުރާނަމަ، (އެބަހީ: އެމީހާގެ މިލްކުގައި، މުދަލެއްހުރިނަމަ) ހެޔޮގޮތުގައި މައިންބަފައިންނާއި ގާތްތިމާގެ މީހުންނަށް ވަސިއްޔަތްކުރުން ތިޔަބައިމީހުންގެ މައްޗަށް ފަރުޟުކުރައްވައިފިއެވެ. (އެކަންއޮތީ) ތަގުވާވެރިންގެ މައްޗަށްއޮތް ހައްގެއް ކަމުގައެވެ.","",""],["₂ سورة البقرة","181","فَمَنۢ بَدَّلَهُۥ بَعۡدَ مَا سَمِعَهُۥ فَإِنَّمَآ إِثۡمُهُۥ عَلَى ٱلَّذِينَ يُبَدِّلُونَهُۥٓۚ إِنَّ ٱللَّهَ سَمِيعٌ عَلِيمٞ ١٨١","فمن بدله بعد ما سمعه فإنما إثمه على الذين يبدلونه إن الله سميع عليم","ފަހެ، އެ ވަސިއްޔަތް އިވުމަށްފަހު، އެ ވަސިއްޔަތް ބަދަލުކުޅަ މީހާ (ދަންނާށެވެ!) ހަމަކަށަވަރުން، އެކަމުގެ ފާފަ އޮތީ، އެކަން ބަދަލުކުރާ މީހުންގެ މައްޗަށެވެ. ހަމަކަށަވަރުން، ﷲއީ މޮޅަށް އައްސަވާވޮޑިގެންވާ މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","182","فَمَنۡ خَافَ مِن مُّوصٖ جَنَفًا أَوۡ إِثۡمٗا فَأَصۡلَحَ بَيۡنَهُمۡ فَلَآ إِثۡمَ عَلَيۡهِۚ إِنَّ ٱللَّهَ غَفُورٞ رَّحِيمٞ ١٨٢","فمن خاف من موص جنفا أو إثما فأصلح بينهم فلا إثم عليه إن الله غفور رحيم","ފަހެ، ވަސިއްޔަތްކުރާ މީހެއްގެ ފަރާތުން ބޭއިންސާފު ގޮތެއް ނުވަތަ ފާފަވެރިވާ ގޮތެއް ހިނގައިފާނެކަމަށް ބިރުގެން އެއުރެންގެ މެދުގައި (އެބަހީ: ވާރުތަވެރިންގެ މެދުގައި) ސުލްހަ ކޮށްފި މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާގެ މައްޗަކަށް ފާފައެއް ނެތެވެ. (އެބަހީ: ކުރިން ނަންގަނެވުނު ވަސިއްޔަތް ބަދަލުކުރުމުގެ ފާފަ އެމީހެއްގެ މައްޗަކަށް ނެތެވެ.) ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","183","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ كُتِبَ عَلَيۡكُمُ ٱلصِّيَامُ كَمَا كُتِبَ عَلَى ٱلَّذِينَ مِن قَبۡلِكُمۡ لَعَلَّكُمۡ تَتَّقُونَ ١٨٣","يا أيها الذين آمنوا كتب عليكم الصيام كما كتب على الذين من قبلكم لعلكم تتقون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ ކުރީގެ މީހުންގެ މައްޗަށް ފަރުޟުކުރެއްވި ފަދައިން ތިޔަބައިމީހުންގެ މައްޗަށްވެސް ރޯދަ ފަރުޟުކުރައްވައިފިއެވެ. (އެއީ) ތިޔަބައިމީހުން ތަގުވާވެރި ވުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","184","أَيَّامٗا مَّعۡدُودَٰتٖۚ فَمَن كَانَ مِنكُم مَّرِيضًا أَوۡ عَلَىٰ سَفَرٖ فَعِدَّةٞ مِّنۡ أَيَّامٍ أُخَرَۚ وَعَلَى ٱلَّذِينَ يُطِيقُونَهُۥ فِدۡيَةٞ طَعَامُ مِسۡكِينٖۖ فَمَن تَطَوَّعَ خَيۡرٗا فَهُوَ خَيۡرٞ لَّهُۥۚ وَأَن تَصُومُواْ خَيۡرٞ لَّكُمۡ إِن كُنتُمۡ تَعۡلَمُونَ ١٨٤","أياما معدودات فمن كان منكم مريضا أو على سفر فعدة من أيام أخر وعلى الذين يطيقونه فدية طعام مسكين فمن تطوع خيرا فهو خير له وأن تصوموا خير لكم إن كنتم تعلمون","(ރޯދަހިފަންވީ) އަދަދު ކަނޑައެޅިގެންވާ ދުވަސްތަކެއް ގައެވެ. ފަހެ، ތިޔަބައިމީހުންގެ ތެރެއިން ބަލިވެއުޅޭ މީހާ ނުވަތަ ދަތުރެއްގެ މަތީގައިވާ މީހާ (ރަމަޟާން މަހުގެ ރޯދަ ދޫކޮށްލައިފިނަމަ) އެހެން ދުވަސްތަކަކުން އެ އަދަދު ހަމަކުރުން ހުށްޓެވެ. އަދި އުނދަގޫކަމާއެކު އެކަމަށް ކުޅަދާނަވާ މީހުންގެ މައްޗަށްއޮތީ، (ރޯދަ ދޫކޮށްލުމާއެކު) ފިދުޔަ ދިނުމެވެ. (ފިދުޔަގެ މިންވަރަކީ) މިސްކީނަކަށް ކާންދޭ މިންވަރެވެ. ފަހެ، ތަޠައްވުޢުގެ ގޮތުން އިތުރު ހެޔޮކަމެއް ކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެކަންތައް އެމީހަކަށް ހެޔޮކަން ބޮޑެވެ. އަދި ތިޔަބައިމީހުން ރޯދަހިފުން ތިޔަބައިމީހުންނަށް ހެޔޮކަން ބޮޑެވެ. އެކަން ތިޔަބައިމީހުން ދަންނާނެ ނަމައެވެ.","",""],["₂ سورة البقرة","185","شَهۡرُ رَمَضَانَ ٱلَّذِيٓ أُنزِلَ فِيهِ ٱلۡقُرۡءَانُ هُدٗى لِّلنَّاسِ وَبَيِّنَٰتٖ مِّنَ ٱلۡهُدَىٰ وَٱلۡفُرۡقَانِۚ فَمَن شَهِدَ مِنكُمُ ٱلشَّهۡرَ فَلۡيَصُمۡهُۖ وَمَن كَانَ مَرِيضًا أَوۡ عَلَىٰ سَفَرٖ فَعِدَّةٞ مِّنۡ أَيَّامٍ أُخَرَۗ يُرِيدُ ٱللَّهُ بِكُمُ ٱلۡيُسۡرَ وَلَا يُرِيدُ بِكُمُ ٱلۡعُسۡرَ وَلِتُكۡمِلُواْ ٱلۡعِدَّةَ وَلِتُكَبِّرُواْ ٱللَّهَ عَلَىٰ مَا هَدَىٰكُمۡ وَلَعَلَّكُمۡ تَشۡكُرُونَ ١٨٥","شهر رمضان الذي أنزل فيه القرآن هدى للناس وبينات من الهدى والفرقان فمن شهد منكم الشهر فليصمه ومن كان مريضا أو على سفر فعدة من أيام أخر يريد الله بكم اليسر ولا يريد بكم العسر ولتكملوا العدة ولتكبروا الله على ما هداكم ولعلكم تشكرون","ރަމަޟާން މަހަކީ، އެމަހެއްގައި ގުރްއާން ބާވައިލެއްވި މަހެވެ. (އެ ގުރްއާން ބާވައިލެއްވީ) މީސްތަކުންނަށް ހުރި ތެދުމަގެއް ކަމުގައްޔާއި ހިދާޔަތާއި ހައްގާއި ބާތިލު ވަކިކޮށްދެނިވި ހެކިތަކެއް ކަމުގައެވެ. ފަހެ، ތިޔަބައިމީހުންގެ ތެރެއިން އެ މައްސަރުގައި ޙާޒިރުުވެ ހުރެއްޖެމީހާ، އެ މަހުގެ ރޯދަ ހިފާހުށި ކަމެވެ! އަދި ބަލިވެއުޅޭ މީހާ ނުވަތަ ދަތުރެއްގެ މަތީގައިވާ މީހާ، (އެ މައްސަރުގެ ރޯދަ ދޫކޮށްލައިފިނަމަ) އެހެންދުވަސްތަކަކުން އެ އަދަދު ހަމަކުރުން ހުށްޓެވެ. ﷲ، ތިޔަބައިމީހުންނަށް ލުއިފަސޭހަގޮތް އިރާދަކުރައްވަތެވެ. އަދި ދަތި އުނދަގޫގޮތް ތިޔަބައިމީހުންނަކަށް އިރާދައެއް ނުކުރައްވަތެވެ. (މިކަންތައްތައް މިގޮތަށް ކަނޑައަޅުއްވާފައިވަނީ) ތިޔަބައިމީހުން އެ މައްސަރުގެ ދުވަސްތަކުގެ އަދަދު ފުރިހަމަ ކުރުމަށްޓަކައެވެ. އަދި ތިޔަބައިމީހުންނަށް ތެދުމަގު ދެއްކެވިކަން މައްޗަށް ﷲއަށް ތަކްބީރު ކިޔައި އުޅުމަށްޓަކައެވެ. އަދި ތިޔަބައިމީހުން (އެކަލާނގެއަށް) ޝުކުރުވެރި ވުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","186","وَإِذَا سَأَلَكَ عِبَادِي عَنِّي فَإِنِّي قَرِيبٌۖ أُجِيبُ دَعۡوَةَ ٱلدَّاعِ إِذَا دَعَانِۖ فَلۡيَسۡتَجِيبُواْ لِي وَلۡيُؤۡمِنُواْ بِي لَعَلَّهُمۡ يَرۡشُدُونَ ١٨٦","وإذا سألك عبادي عني فإني قريب أجيب دعوة الداع إذا دعان فليستجيبوا لي وليؤمنوا بي لعلهم يرشدون","އަދި ތިމަންރަސްކަލާނގެއާމެދު ތިމަންރަސްކަލާނގެ އަޅުން ކަލޭގެފާނާ ސުވާލު ކޮށްފިނަމަ، (ކަލޭގެފާނު ވިދާޅުވާށެވެ!) ފަހެ، ހަމަކަށަވަރުން ތިމަންރަސްކަލާނގެއީ (އެއުރެންނާ) ކުއްތަންވެ ވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ދުއާ ކޮށްފިނަމަ ދުއާކުރި މީހާގެ ދުއާ ތިމަންރަސްކަލާނގެ އިޖާބަ ކުރައްވަމެވެ. ފަހެ، އެއުރެން (އެބަހީ: ތިމަންރަސްކަލާނގެ އަޅުން) ތިމަންރަސްކަލާނގެއަށް އިޖާބަދޭހުށިކަމެވެ! އަދި އެއުރެން ތިމަން ރަސްކަލާނގެއަށް އީމާން ވާހުށިކަމެވެ! (އެއީ) އެއުރެންނަށް ތެދުމަގު ލިބުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","187","أُحِلَّ لَكُمۡ لَيۡلَةَ ٱلصِّيَامِ ٱلرَّفَثُ إِلَىٰ نِسَآئِكُمۡۚ هُنَّ لِبَاسٞ لَّكُمۡ وَأَنتُمۡ لِبَاسٞ لَّهُنَّۗ عَلِمَ ٱللَّهُ أَنَّكُمۡ كُنتُمۡ تَخۡتَانُونَ أَنفُسَكُمۡ فَتَابَ عَلَيۡكُمۡ وَعَفَا عَنكُمۡۖ فَٱلۡـَٰٔنَ بَٰشِرُوهُنَّ وَٱبۡتَغُواْ مَا كَتَبَ ٱللَّهُ لَكُمۡۚ وَكُلُواْ وَٱشۡرَبُواْ حَتَّىٰ يَتَبَيَّنَ لَكُمُ ٱلۡخَيۡطُ ٱلۡأَبۡيَضُ مِنَ ٱلۡخَيۡطِ ٱلۡأَسۡوَدِ مِنَ ٱلۡفَجۡرِۖ ثُمَّ أَتِمُّواْ ٱلصِّيَامَ إِلَى ٱلَّيۡلِۚ وَلَا تُبَٰشِرُوهُنَّ وَأَنتُمۡ عَٰكِفُونَ فِي ٱلۡمَسَٰجِدِۗ تِلۡكَ حُدُودُ ٱللَّهِ فَلَا تَقۡرَبُوهَاۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ ءَايَٰتِهِۦ لِلنَّاسِ لَعَلَّهُمۡ يَتَّقُونَ ١٨٧","أحل لكم ليلة الصيام الرفث إلى نسائكم هن لباس لكم وأنتم لباس لهن علم الله أنكم كنتم تختانون أنفسكم فتاب عليكم وعفا عنكم فالآن باشروهن وابتغوا ما كتب الله لكم وكلوا واشربوا حتى يتبين لكم الخيط الأبيض من الخيط الأسود من الفجر ثم أتموا الصيام إلى الليل ولا تباشروهن وأنتم عاكفون في المساجد تلك حدود الله فلا تقربوها كذلك يبين الله آياته للناس لعلهم يتقون","ރޯދަޔަށް ތިބޭރޭ ތިޔަބައިމީހުންގެ އަނބިންގެ ގާތަށްގޮސް ރޭކުރުން ތިޔަބައިމީހުންނަށް ހުއްދަ ކުރައްވައިފިއެވެ. އެކަނބަލުންނީ ތިޔަބައިމީހުންނަށް ފޭރާމެކެވެ. އަދި ތިޔަބައިމީހުންނީ އެކަނބަލުންނަށް ފޭރާމެކެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތަކަށް ޚިޔާނަތް ތެރިވަމުން ދިޔަކަން، ﷲ، ދެނެވޮޑިގެންވެއެވެ. ދެންފަހެ، ތިޔަބައިމީހުންގެ މައްޗަށް ތައުބާ ލައްވައި، ތިޔަބައިމީހުންގެ ކިބައިން އަފޫކުރައްވައިފިއެވެ. ފަހެ، މިހާރު ތިޔަބައިމީހުން އެކަނބަލުންނާ ބީހިއުޅޭށެވެ! (އެބަހީ: ޖިމާއު ވުން ހުއްދަ ކުރައްވައިފިއެވެ.) އަދި ތިޔަބައިމީހުންނަށްޓަކައި ﷲ ކަނޑައަޅުއްވާފައިވާ ގޮތް އެދޭށެވެ! އަދި ތިޔަބައިމީހުން ކައިބޮއި އުޅޭށެވެ! ފަޖުރުގެ ސަބަބުން ރޭގަނޑުގެ އަނދިރިކަމުގެ ތެރެއިން ފަތިހުގެ އަލިކަން ފާޅުވެ އެނގިއްޖައުމަށް ދާނދެނެވެ. ދެން އެއަށްފަހު، ރޭވެއްޖައުމަށް ދާނދެން ތިޔަބައިމީހުން ރޯދަ ފުރިހަމަ ކުރާށެވެ! އަދި ތިޔަބައިމީހުން މިސްކިތްތަކުގައި އިއުތިކާފަށް ތިބޭއިރު އެކަނބަލުންނާ ތިޔަބައިމީހުން ބީހި ނޫޅޭށެވެ! (އެބަހީ: ޖިމާއު ނުވާށެވެ!) އެއީ، ﷲ ކަނޑައަޅުއްވާފައިވާ އިންތަކެވެ. ފަހެ، އެ އިންތަކާ ތިޔަބައިމީހުން ކައިރި ނުވާށެވެ! (އެބަހީ: އެ އިންތައް ފަހަނަޅައި ނުދާށެވެ!) އެފަދައިން ﷲ، އެކަލާނގެ އާޔަތްތައް މީސްތަކުންނަށް ބަޔާން ކޮށް ދެއްވަނީ އެއުރެން ތަގުވާވެރި ވުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","188","وَلَا تَأۡكُلُوٓاْ أَمۡوَٰلَكُم بَيۡنَكُم بِٱلۡبَٰطِلِ وَتُدۡلُواْ بِهَآ إِلَى ٱلۡحُكَّامِ لِتَأۡكُلُواْ فَرِيقٗا مِّنۡ أَمۡوَٰلِ ٱلنَّاسِ بِٱلۡإِثۡمِ وَأَنتُمۡ تَعۡلَمُونَ ١٨٨","ولا تأكلوا أموالكم بينكم بالباطل وتدلوا بها إلى الحكام لتأكلوا فريقا من أموال الناس بالإثم وأنتم تعلمون","އަދި ތިޔަބައިމީހުންގެ މުދާތައް ތިޔަބައިމީހުންގެ މެދުގައި ބާތިލު ގޮތުގައި ނުކާށެވެ! އަދި ތިޔަބައިމީހުން ދެނެތިބެގެންމެ، ފާފަވެރި ގޮތުގައި މީސްތަކުންގެ މުދާތަކުގެ ތެރެއިން ބައެއް ކެއުމަށްޓަކައި އެ މުދާތައް (އެބަހީ: އެ މުދާތަކުން ބައެއް) ހާކިމުންނަށް ނުދޭށެވެ!","",""],["₂ سورة البقرة","189","۞يَسۡـَٔلُونَكَ عَنِ ٱلۡأَهِلَّةِۖ قُلۡ هِيَ مَوَٰقِيتُ لِلنَّاسِ وَٱلۡحَجِّۗ وَلَيۡسَ ٱلۡبِرُّ بِأَن تَأۡتُواْ ٱلۡبُيُوتَ مِن ظُهُورِهَا وَلَٰكِنَّ ٱلۡبِرَّ مَنِ ٱتَّقَىٰۗ وَأۡتُواْ ٱلۡبُيُوتَ مِنۡ أَبۡوَٰبِهَاۚ وَٱتَّقُواْ ٱللَّهَ لَعَلَّكُمۡ تُفۡلِحُونَ ١٨٩","يسألونك عن الأهلة قل هي مواقيت للناس والحج وليس البر بأن تأتوا البيوت من ظهورها ولكن البر من اتقى وأتوا البيوت من أبوابها واتقوا الله لعلكم تفلحون","ހުޅެވިހަނދާމެދު ކަލޭގެފާނާ އެއުރެން ސުވާލުކުރެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއީ މީސްތަކުންނަށް (އެކިއެކި ކަންކަމުގެ) ވަގުތު އެނގުމަށާއި ހައްޖުގެ ދުވަސްތައް ފާހަގަކުރުމަށްވާ އެއްޗެކެވެ. އަދި ގޭގޭގެ ފުރަގަހުން ވަދެއުޅުން އެއީ ހެޔޮކަމެއް ކަމުގައެއް ނުވެއެވެ. އެހެނެއްކަމަކު، ހެޔޮކަންކުރާ މީހާއީ، ﷲއަށް ތަގުވާވެރިވެއްޖެ މީހެކެވެ. އަދި ތިޔަބައިމީހުން ގޭގެޔަށް، އެ ގޭގޭގެ ދޮރުދޮރުން ވަދެއުޅޭށެވެ! އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އެއީ، ތިޔަބައިމީހުން ދިންނަވައި ނަސީބު ލިބުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","190","وَقَٰتِلُواْ فِي سَبِيلِ ٱللَّهِ ٱلَّذِينَ يُقَٰتِلُونَكُمۡ وَلَا تَعۡتَدُوٓاْۚ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلۡمُعۡتَدِينَ ١٩٠","وقاتلوا في سبيل الله الذين يقاتلونكم ولا تعتدوا إن الله لا يحب المعتدين","ތިޔަބައިމީހުންނާ ހަނގުރާމަކުރާ މީހުންނާ ތިޔަބައިމީހުން ﷲގެ މަގުގައި ހަނގުރާމަ ކުރާށެވެ! އަދި (އެކަމުގައި) ތިޔަބައިމީހުން (އިސްވެ ހަނގުރާމަ ފެށުމުގެ ގޮތުން) ހައްދުފަހަނަޅައި ނުދާށެވެ! ހަމަކަށަވަރުން (އިސްވެ ހަނގުރާމަ ފެށުމުގެ ގޮތުން) ހައްދުފަހަނަޅައިދާ މީހުންދެކެ ﷲ ލޯބިވެވޮޑިގެނެއްނުވެއެވެ.","",""],["₂ سورة البقرة","191","وَٱقۡتُلُوهُمۡ حَيۡثُ ثَقِفۡتُمُوهُمۡ وَأَخۡرِجُوهُم مِّنۡ حَيۡثُ أَخۡرَجُوكُمۡۚ وَٱلۡفِتۡنَةُ أَشَدُّ مِنَ ٱلۡقَتۡلِۚ وَلَا تُقَٰتِلُوهُمۡ عِندَ ٱلۡمَسۡجِدِ ٱلۡحَرَامِ حَتَّىٰ يُقَٰتِلُوكُمۡ فِيهِۖ فَإِن قَٰتَلُوكُمۡ فَٱقۡتُلُوهُمۡۗ كَذَٰلِكَ جَزَآءُ ٱلۡكَٰفِرِينَ ١٩١","واقتلوهم حيث ثقفتموهم وأخرجوهم من حيث أخرجوكم والفتنة أشد من القتل ولا تقاتلوهم عند المسجد الحرام حتى يقاتلوكم فيه فإن قاتلوكم فاقتلوهم كذلك جزاء الكافرين","އަދި ތިޔަބައިމީހުންނަށް އެއުރެން (އެބަހީ: ތިޔަބައިމީހުންނާ ހަނގުރާމަކުރާ މީހުން) ފެނުނު ކޮންމެ ތަނަކުން އެއުރެން ގަތުލުކުރާށެވެ! އަދި އެއުރެން ތިޔަބައިމީހުން ނެރުނުތަނުން ތިޔަބައިމީހުން އެއުރެން ނެރޭށެވެ! އަދި ގަތުލުކުރުމަށްވުރެ ފިތުނަވެރިކަމުގެ ނުބައިކަން ބޮޑެވެ. އަދި ހުރުމަތް ތެރިވެގެންވާ މިސްކިތުގައި އެއުރެން ތިޔަބައިމީހުންނާ ހަނގުރާމަކޮށްފުމަށް ދާނދެން ތިޔަބައިމީހުން އެއުރެންނާ ހަނގުރާމަ ނުކުރާށެވެ! އެއުރެން ތިޔަބައިމީހުންނާ ހަނގުރާމަކޮށްފިނަމަ، ތިޔަބައިމީހުންވެސް (ހަނގުރާމަކޮށް) އެއުރެން ގަތުލުކުރާށެވެ! ކާފިރުންގެ ޖަޒާ ވަނީ އެފަދައިންނެވެ.","",""],["₂ سورة البقرة","192","فَإِنِ ٱنتَهَوۡاْ فَإِنَّ ٱللَّهَ غَفُورٞ رَّحِيمٞ ١٩٢","فإن انتهوا فإن الله غفور رحيم","ފަހެ، އެއުރެން (ހަނގުރާމަ) ހުއްޓާލައިފިނަމަ، (ތިޔަބައިމީހުންވެސް ހަނގުރާމަ ހުއްޓާލާށެވެ! އަދި ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","193","وَقَٰتِلُوهُمۡ حَتَّىٰ لَا تَكُونَ فِتۡنَةٞ وَيَكُونَ ٱلدِّينُ لِلَّهِۖ فَإِنِ ٱنتَهَوۡاْ فَلَا عُدۡوَٰنَ إِلَّا عَلَى ٱلظَّـٰلِمِينَ ١٩٣","وقاتلوهم حتى لا تكون فتنة ويكون الدين لله فإن انتهوا فلا عدوان إلا على الظالمين","އަދި (ދީނާ ދެކޮޅަށް އުފައްދާ) ފިތުނަވެރިކަން ނެތިއްޖައުމަށް ދާނދެން އަދި ދީން، ﷲއަށް ޚާލިސް ވެއްޖައުމަށް ދާނދެން ތިޔަބައިމީހުން އެއުރެންނާ ހަނގުރާމަ ކުރާށެވެ! ފަހެ، އެއުރެން އެކަން ހުއްޓާލައިފިނަމަ، އަނިޔާވެރިވާ ބަޔެއްގެ މައްޗަށް މެނުވީ އަދާވަތް ތެރި ވުމެއް ނެތެވެ.","",""],["₂ سورة البقرة","194","ٱلشَّهۡرُ ٱلۡحَرَامُ بِٱلشَّهۡرِ ٱلۡحَرَامِ وَٱلۡحُرُمَٰتُ قِصَاصٞۚ فَمَنِ ٱعۡتَدَىٰ عَلَيۡكُمۡ فَٱعۡتَدُواْ عَلَيۡهِ بِمِثۡلِ مَا ٱعۡتَدَىٰ عَلَيۡكُمۡۚ وَٱتَّقُواْ ٱللَّهَ وَٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ مَعَ ٱلۡمُتَّقِينَ ١٩٤","الشهر الحرام بالشهر الحرام والحرمات قصاص فمن اعتدى عليكم فاعتدوا عليه بمثل ما اعتدى عليكم واتقوا الله واعلموا أن الله مع المتقين","ހުރުމަތް ތެރިވެގެންވާ މަހަށް ހުރުމަތް ތެރިވެގެންވާ މަހެވެ. ހުރުމަތްތައް ކަނޑައިފުމަކީ، ބަދަލުހިފުން އޮންނަ ކަމެކެވެ. (އެބަހީ: ހުރުމަތް ތެރިވެގެންވާ މައްސަރެއްގައި މުޝްރިކުން ހަނގުރާމަ ކުޅަފަދައިން، އެފަދަ މައްސަރެއްގައި މުޝްރިކުންނާ ހަނގުރާމަ ކުޅައުމަކީ ކުރުން އެންމެ ރަނގަޅު ކަމެކެވެ.) ފަހެ، ތިޔަބައިމީހުންގެ މައްޗަށް ދެކޮޅުވެރިވެ ހަމަލާ ދިން ބަޔެއްގެ މައްޗަށް އެއުރެން ދެކޮޅުވެރިވެ ހަމަލާ ދިން ފަދަޔަކުން ތިޔަބައިމީހުން ދެކޮޅުވެރިވެ ހަމަލާ ދޭށެވެ! އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! ހަމަކަށަވަރުން، ﷲ ވޮޑިގެންވަނީ ތަގުވާވެރިންނާ އެކުގައިކަން ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₂ سورة البقرة","195","وَأَنفِقُواْ فِي سَبِيلِ ٱللَّهِ وَلَا تُلۡقُواْ بِأَيۡدِيكُمۡ إِلَى ٱلتَّهۡلُكَةِ وَأَحۡسِنُوٓاْۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلۡمُحۡسِنِينَ ١٩٥","وأنفقوا في سبيل الله ولا تلقوا بأيديكم إلى التهلكة وأحسنوا إن الله يحب المحسنين","ﷲގެ މަގުގައި ތިޔަބައިމީހުން ހޭދަކުރާށެވެ! އަދި ތިޔަބައިމީހުންގެ އަތްތަކުން ތިޔަބައިމީހުންގެ ނަފްސުތައް ހަލާކުގެ ތެރެޔަށް އެއްލާނުލާށެވެ! އަދި އިހްސާން ތެރިވާށެވެ! ހަމަކަށަވަރުން، އިހްސާން ތެރިންދެކެ ﷲ ލޯބިވެވޮޑިގެންވެއެވެ.","",""],["₂ سورة البقرة","196","وَأَتِمُّواْ ٱلۡحَجَّ وَٱلۡعُمۡرَةَ لِلَّهِۚ فَإِنۡ أُحۡصِرۡتُمۡ فَمَا ٱسۡتَيۡسَرَ مِنَ ٱلۡهَدۡيِۖ وَلَا تَحۡلِقُواْ رُءُوسَكُمۡ حَتَّىٰ يَبۡلُغَ ٱلۡهَدۡيُ مَحِلَّهُۥۚ فَمَن كَانَ مِنكُم مَّرِيضًا أَوۡ بِهِۦٓ أَذٗى مِّن رَّأۡسِهِۦ فَفِدۡيَةٞ مِّن صِيَامٍ أَوۡ صَدَقَةٍ أَوۡ نُسُكٖۚ فَإِذَآ أَمِنتُمۡ فَمَن تَمَتَّعَ بِٱلۡعُمۡرَةِ إِلَى ٱلۡحَجِّ فَمَا ٱسۡتَيۡسَرَ مِنَ ٱلۡهَدۡيِۚ فَمَن لَّمۡ يَجِدۡ فَصِيَامُ ثَلَٰثَةِ أَيَّامٖ فِي ٱلۡحَجِّ وَسَبۡعَةٍ إِذَا رَجَعۡتُمۡۗ تِلۡكَ عَشَرَةٞ كَامِلَةٞۗ ذَٰلِكَ لِمَن لَّمۡ يَكُنۡ أَهۡلُهُۥ حَاضِرِي ٱلۡمَسۡجِدِ ٱلۡحَرَامِۚ وَٱتَّقُواْ ٱللَّهَ وَٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ شَدِيدُ ٱلۡعِقَابِ ١٩٦","وأتموا الحج والعمرة لله فإن أحصرتم فما استيسر من الهدي ولا تحلقوا رءوسكم حتى يبلغ الهدي محله فمن كان منكم مريضا أو به أذى من رأسه ففدية من صيام أو صدقة أو نسك فإذا أمنتم فمن تمتع بالعمرة إلى الحج فما استيسر من الهدي فمن لم يجد فصيام ثلاثة أيام في الحج وسبعة إذا رجعتم تلك عشرة كاملة ذلك لمن لم يكن أهله حاضري المسجد الحرام واتقوا الله واعلموا أن الله شديد العقاب","ތިޔަބައިމީހުން ﷲއަށްޓަކައި ހައްޖާއި އުމްރާ ފުރިހަމައަށް އަދާކުރާށެވެ! ފަހެ، އެކަމުގައި ތިޔަބައިމީހުން އިޙްޞާރު ވެއްޖެނަމަ، (އެބަހީ: ދެކޮޅުވެރި ބަޔެއްގެ ސަބަބުން، ނުވަތަ އެނޫން ކަމެއްގެ ސަބަބުން ނަމަވެސް، ހައްޖު ވުމަށް ނުވަތައުމްރާ ވުމަށް ދިޔުމުގެ މަގު ބަންދުވެއްޖެނަމަ) ހަދްޔުގެތެރެއިން ތަނަވަސްވެ ލިބުނު އެއްޗެއް ކަތިލުން ހުށްޓެވެ. އަދި ހަދްޔު، އެ ކަތިލުމުގެ މަޙައްލަށް ފޯރައްޖައުމަށް ދާނދެން ތިޔަބައިމީހުން ބޯ ނުބާލާށެވެ! ފަހެ، ތިޔަބައިމީހުންގެ ތެރެއިން ބަލިވެއްޖެމީހާ ނުވަތަ ބޮލުގައި ބައްޔެއް ހުރެއްޖެމީހާ (އެކަންކަމުގެ ސަބަބުން ބޯބާލައިފިނަމަ) ފަހެ، ރޯދައިން، ނުވަތަ ސަދަގާތެއް ދިނުމުން ނުވަތަ ކަތިލުމަކުން ފިދުޔެއް ދިނުން ހުށްޓެވެ. ފަހެ، ތިޔަބައިމީހުންނަށް އަމާން ކަން ލިބިއްޖެނަމައުމްރާއަށްފަހު، ހައްޖާ ހަމަޔަށް ދާނދެން އަރާމު ލިބިގެންފިމީހާ (އެބަހީ: ހައްޖުގެ ދުވަސްވަރުގައިއުމްރާގެ އަޅުކަން ނިމި، އިހްރާމް ކަނޑައިފުމުން، އިހްރާމްގެ ސަބަބުން ހަރާމްވާ ކަންތައްތައް ހުއްދަވުމަށްފަހު، މައްކާގައި ހުރެ އަލުން ހައްޖަށް އިހްރާމް ބަނދެފި މީހާ) ހަދްޔުގެތެރެއިން ތަނަވަސްވެ ލިބުނު އެއްޗެއް ކަތިލުން ހުށްޓެވެ. ފަހެ، އެފަދަ އެއްޗެއް ނުލިބިއްޖެމީހާ ހައްޖުގެތެރޭގައި ތިން ދުވަހު، އަދި ހައްޖުން އެބުރި އައުމަށްފަހު ހަތް ދުވަހު ރޯދަހިފުން ހުށްޓެވެ. އެއީ ފުރިހަމަ ދިހަ ދުވަހެވެ. އެކަންއޮތީ، އެމީހެއްގެ އަހުލުވެރިން ހުރުމަތް ތެރި ވެގެންވާ މިސްކިތް ހުރި ރަށުގެ ވަޒަންވެރިން ކަމުގައި ނުވާ މީހަކަށެވެ. އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ހަމަކަށަވަރުން، ﷲއީ އުގޫބާތް ގަދަފަދަވެގެންވާ ރަސްކަލާނގެކަން ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₂ سورة البقرة","197","ٱلۡحَجُّ أَشۡهُرٞ مَّعۡلُومَٰتٞۚ فَمَن فَرَضَ فِيهِنَّ ٱلۡحَجَّ فَلَا رَفَثَ وَلَا فُسُوقَ وَلَا جِدَالَ فِي ٱلۡحَجِّۗ وَمَا تَفۡعَلُواْ مِنۡ خَيۡرٖ يَعۡلَمۡهُ ٱللَّهُۗ وَتَزَوَّدُواْ فَإِنَّ خَيۡرَ ٱلزَّادِ ٱلتَّقۡوَىٰۖ وَٱتَّقُونِ يَـٰٓأُوْلِي ٱلۡأَلۡبَٰبِ ١٩٧","الحج أشهر معلومات فمن فرض فيهن الحج فلا رفث ولا فسوق ولا جدال في الحج وما تفعلوا من خير يعلمه الله وتزودوا فإن خير الزاد التقوى واتقون يا أولي الألباب","ހައްޖުގެ ވަގުތަކީ ކަނޑައެޅި އެނގިގެންވާ މައްސަރު ތަކެކެވެ. ފަހެ، އެ މައްސަރުތަކުގައި ހައްޖު ފަރުޟު ކޮށްގެންފި މީހާ (އެބަހީ: ހައްޖު ވުމަށް ގަސްދު ކޮށް އިހްރާމް ބަނދެފިމީހާ، ދަންނާށެވެ!) ފަހެ ހައްޖު ވުމުގެ ތެރޭގައި ޖިމާއު ވުމެއް، އަދި އުރެދުމެއް، އަދި އަރާރުންވުމެއްވެސް ނެތެވެ. އަދި، (ﷲއީ، ހުރިހާ ކަމެއް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެ ކަމަށްވާތީ) ހެޔޮކަމުގެ ތެރެއިން ތިޔަބައިމީހުންކުރާ ކޮންމެ ކަމެއް (ވެސް) ﷲ ދެނެވޮޑިގެންވެއެވެ. އަދި ތިޔަބައިމީހުން ދަތުރުމަތީގެ ކޮއްތު ލިބިގަންނާށެވެ! ފަހެ، ހަމަކަށަވަރުން އެންމެ މޮޅު ކޮއްތަކީ ތަގުވާއެވެ. އޭ ބުއްދީގެ އަހުލުވެރިންނޭވެ! ތިޔަބައިމީހުން ތިމަންރަސްކަލާނގެއަށް ތަގުވާވެރިވާށެވެ!","",""],["₂ سورة البقرة","198","لَيۡسَ عَلَيۡكُمۡ جُنَاحٌ أَن تَبۡتَغُواْ فَضۡلٗا مِّن رَّبِّكُمۡۚ فَإِذَآ أَفَضۡتُم مِّنۡ عَرَفَٰتٖ فَٱذۡكُرُواْ ٱللَّهَ عِندَ ٱلۡمَشۡعَرِ ٱلۡحَرَامِۖ وَٱذۡكُرُوهُ كَمَا هَدَىٰكُمۡ وَإِن كُنتُم مِّن قَبۡلِهِۦ لَمِنَ ٱلضَّآلِّينَ ١٩٨","ليس عليكم جناح أن تبتغوا فضلا من ربكم فإذا أفضتم من عرفات فاذكروا الله عند المشعر الحرام واذكروه كما هداكم وإن كنتم من قبله لمن الضالين","ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ލިބޭ ފަޟްލު ވަންތަވެރިކަމެއް (އެބަހީ: ވިޔަފާރިކުރުންފަދަ ގޮތްގޮތުން ހޯދާ ތަނަވަސްކަމެއް) ހޯދަން އުޅުމުގައި ތިޔަބައިމީހުންގެ މައްޗަކަށް ކުށެއްނެތެވެ. ދެންފަހެ، ތިޔަބައިމީހުން އަރަފާތުން އެނބުރި އައުމުގެ ދަތުރު ފަށައިގަންނަހިނދު، އަލްމަޝްޢަރުލް ހަރާމްގައި (އެބަހީ: މުޒްދަލިފާ ނިމޭތާނގައިވާ ގުޒަޙް ފަރުބަދަ ކައިރީގައި) ތިޔަބައިމީހުން ﷲ ހަނދުމަކުރާށެވެ! (އެބަހީ: ތަލްބިޔާ ކިޔައި، ދުއާކުރާށެވެ!) އަދި އެކަލާނގެ ތިޔަބައިމީހުންނަށް ތެދުމަގު ދައްކަވައި އެންގެވި ފަދައިން، ތިޔަބައިމީހުން އެކަލާނގެ ހަނދުމަކުރާށެވެ! އޭގެކުރިން ތިޔަބައިމީހުން ވެފައިވީ މަގުފުރެދިގެންވާ މީހުންގެ ތެރެއިންކަން ކަށަވަރެވެ.","",""],["₂ سورة البقرة","199","ثُمَّ أَفِيضُواْ مِنۡ حَيۡثُ أَفَاضَ ٱلنَّاسُ وَٱسۡتَغۡفِرُواْ ٱللَّهَۚ إِنَّ ٱللَّهَ غَفُورٞ رَّحِيمٞ ١٩٩","ثم أفيضوا من حيث أفاض الناس واستغفروا الله إن الله غفور رحيم","ދެން (އަރަފާތުން މުޒްދަލިފާ ޔަށް) އެނބުރި އަންނަ މީސްތަކުންނާއެކު ތިޔަބައިމީހުންވެސް އެނބުރި އަންނާށެވެ! އަދި ތިޔަބައިމީހުން ﷲގެ ހަޒުރަތުން ފާފަ ފުއްސަވައި ދެއްވުމަށް އެދޭށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","200","فَإِذَا قَضَيۡتُم مَّنَٰسِكَكُمۡ فَٱذۡكُرُواْ ٱللَّهَ كَذِكۡرِكُمۡ ءَابَآءَكُمۡ أَوۡ أَشَدَّ ذِكۡرٗاۗ فَمِنَ ٱلنَّاسِ مَن يَقُولُ رَبَّنَآ ءَاتِنَا فِي ٱلدُّنۡيَا وَمَا لَهُۥ فِي ٱلۡأٓخِرَةِ مِنۡ خَلَٰقٖ ٢٠٠","فإذا قضيتم مناسككم فاذكروا الله كذكركم آباءكم أو أشد ذكرا فمن الناس من يقول ربنا آتنا في الدنيا وما له في الآخرة من خلاق","ފަހެ، ތިޔަބައިމީހުންގެ ހައްޖުގެ އަޅުކަންތައް އަދާކޮށް ނިމިއްޖެހިނދެއްގައި ތިޔަބައިމީހުން، ތިޔަބައިމީހުންގެ ކާބަފައިން ހަނދުމަކޮށް އުޅުނު ފަދައިން ނުވަތަ އެއަށްވުރެ ގަދަވެގެންވާ ހަނދުމަކުޅައުމަކުން ތިޔަބައިމީހުން ﷲ ހަނދުމަކުރާށެވެ! [އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! ދުނިޔޭގައި އަޅަމެންނަށް (ހެޔޮކަން) ދެއްވާނދޭވެ] އޭ ކިޔައި ދުއާކުރާ މީހުން، މީސްތަކުންގެ ތެރެއިންވެއެވެ. އެއިން މީހަކަށް އާޚިރަތުގައި އެއްވެސް ނަސީބެއް ނެތެވެ.","",""],["₂ سورة البقرة","201","وَمِنۡهُم مَّن يَقُولُ رَبَّنَآ ءَاتِنَا فِي ٱلدُّنۡيَا حَسَنَةٗ وَفِي ٱلۡأٓخِرَةِ حَسَنَةٗ وَقِنَا عَذَابَ ٱلنَّارِ ٢٠١","ومنهم من يقول ربنا آتنا في الدنيا حسنة وفي الآخرة حسنة وقنا عذاب النار","އަދި [އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! ދުނިޔޭގައި ހެޔޮކަން އަދި އާޚިރަތް ގައިވެސް ހެޔޮކަން އަޅަމެންނަށް ދެއްވާނދޭވެއެވެ. އަދި ނަރަކައިގެ އަޒާބުން އަޅަމެން ދިންނަވާނދޭވެ] އޭ ކިޔައި، ދުއާކުރާ މީހުންވެސް އެއުރެންގެ ތެރެއިންވެއެވެ.","",""],["₂ سورة البقرة","202","أُوْلَـٰٓئِكَ لَهُمۡ نَصِيبٞ مِّمَّا كَسَبُواْۚ وَٱللَّهُ سَرِيعُ ٱلۡحِسَابِ ٢٠٢","أولئك لهم نصيب مما كسبوا والله سريع الحساب","އެއުރެން ހޯދި ހެޔޮކަމުގެ ނަސީބު އެއުރެންނަށް ހުށްޓެވެ. ﷲއީ، ހިސާބު ބެއްލެވުން އަވަސްވެ ވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","203","۞وَٱذۡكُرُواْ ٱللَّهَ فِيٓ أَيَّامٖ مَّعۡدُودَٰتٖۚ فَمَن تَعَجَّلَ فِي يَوۡمَيۡنِ فَلَآ إِثۡمَ عَلَيۡهِ وَمَن تَأَخَّرَ فَلَآ إِثۡمَ عَلَيۡهِۖ لِمَنِ ٱتَّقَىٰۗ وَٱتَّقُواْ ٱللَّهَ وَٱعۡلَمُوٓاْ أَنَّكُمۡ إِلَيۡهِ تُحۡشَرُونَ ٢٠٣","واذكروا الله في أيام معدودات فمن تعجل في يومين فلا إثم عليه ومن تأخر فلا إثم عليه لمن اتقى واتقوا الله واعلموا أنكم إليه تحشرون","އަދަދު ކަނޑައެޅިގެންވާ ދުވަސްތަކެއްގައި ﷲ ހަނދުމަކޮށް (ތަކްބީރު ކިޔައި) އުޅޭށެވެ! ފަހެ، ދެ ދުވަހުގެ ތެރޭގައި (އެކަން ނިންމައި އެނބުރި ދިޔުމަށް) އަވަސްވެގަތްމީހާގެ މައްޗަކަށް ފާފައެއް ނެތެވެ. އަދި (ތިންދުވަހަށް) ލަސްކުޅަމީހާގެ މައްޗަކަށްވެސް ފާފައެއް ނެތެވެ. އެއީ، ތަގުވާވެރިވެއްޖެ މީހަކަށެވެ. އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ހަމަކަށަވަރުން ތިޔަބައިމީހުން މަހުޝަރަށް ފޮނުއްވާނީ، އެކަލާނގެ ހަޒުރަތަށް ކަން، ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₂ سورة البقرة","204","وَمِنَ ٱلنَّاسِ مَن يُعۡجِبُكَ قَوۡلُهُۥ فِي ٱلۡحَيَوٰةِ ٱلدُّنۡيَا وَيُشۡهِدُ ٱللَّهَ عَلَىٰ مَا فِي قَلۡبِهِۦ وَهُوَ أَلَدُّ ٱلۡخِصَامِ ٢٠٤","ومن الناس من يعجبك قوله في الحياة الدنيا ويشهد الله على ما في قلبه وهو ألد الخصام","ދުނިޔަވީ ހަޔާތާމެދު އެމީހަކު ބުނާ ބަހުން ކަލޭގެފާނުގެ ހިތްޕުޅު ރުއްސާލައި، އަދި އޭނާގެ ހިތުގައިވާ ގޮތުގެ މައްޗަށް ﷲ ހެކިކޮށް ބުނާ މީހުން މީސްތަކުންގެ ތެރެއިން ވެއެވެ. އެހިނދު އެމީހާ ވަނީ، ދެކޮޅުވެރިކަން އެންމެ ބޮޑު މީހާ ކަމުގައެވެ.","",""],["₂ سورة البقرة","205","وَإِذَا تَوَلَّىٰ سَعَىٰ فِي ٱلۡأَرۡضِ لِيُفۡسِدَ فِيهَا وَيُهۡلِكَ ٱلۡحَرۡثَ وَٱلنَّسۡلَۚ وَٱللَّهُ لَا يُحِبُّ ٱلۡفَسَادَ ٢٠٥","وإذا تولى سعى في الأرض ليفسد فيها ويهلك الحرث والنسل والله لا يحب الفساد","އަދި އެމީހާ ފުރަގަސްދީ ހިނގައްޖެނަމަ، ބިމުގައި ފަސާދަ އުފެއްދުމަށްޓަކައި އަދި ދަނޑުފަނގާއި ދަރިފަސްކޮޅު ހަލާކުކުރުމަށްޓަކައި ބިމުގައި މަސައްކަތްކޮށް އުޅެތެވެ. ﷲ، ފަސާދަވެރިކަމަކަށް ލޯބިވެވޮޑިގެނެއް ނުވެއެވެ.","",""],["₂ سورة البقرة","206","وَإِذَا قِيلَ لَهُ ٱتَّقِ ٱللَّهَ أَخَذَتۡهُ ٱلۡعِزَّةُ بِٱلۡإِثۡمِۚ فَحَسۡبُهُۥ جَهَنَّمُۖ وَلَبِئۡسَ ٱلۡمِهَادُ ٢٠٦","وإذا قيل له اتق الله أخذته العزة بالإثم فحسبه جهنم ولبئس المهاد","އަދި ﷲއަށް ތަގުވާވެރިވާށޭ އެމީހާޔާ ދިމާޔަށް ބުނެފިނަމަ، ފާފަވެރިވެގަތުމުގެ ބޮޑާކަން އައިސް އޭނާގައި ހިފަތެވެ. ފަހެ، އެމީހާޔަށް ނަރަކަ ފުދެއެވެ. އަދި ހަމަކަށަވަރުން، އެ ތަންމަތީގެ ހުރި ނުބައިކަމުގެ ބޮޑުކަމާއެވެ!","",""],["₂ سورة البقرة","207","وَمِنَ ٱلنَّاسِ مَن يَشۡرِي نَفۡسَهُ ٱبۡتِغَآءَ مَرۡضَاتِ ٱللَّهِۚ وَٱللَّهُ رَءُوفُۢ بِٱلۡعِبَادِ ٢٠٧","ومن الناس من يشري نفسه ابتغاء مرضات الله والله رءوف بالعباد","އަދި ﷲގެ ރުހިވޮޑިގަތުން އެދި (އެކަލާނގެއަށް) ތިމާގެ ނަފްސު ދޫކޮށްލާ މީހުންވެސް މީސްތަކުންގެ ތެރެއިން ވެއެވެ. ﷲއީ، އަޅުތަކުންނާމެދު، ނުހަނު އޯގާވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","208","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ ٱدۡخُلُواْ فِي ٱلسِّلۡمِ كَآفَّةٗ وَلَا تَتَّبِعُواْ خُطُوَٰتِ ٱلشَّيۡطَٰنِۚ إِنَّهُۥ لَكُمۡ عَدُوّٞ مُّبِينٞ ٢٠٨","يا أيها الذين آمنوا ادخلوا في السلم كافة ولا تتبعوا خطوات الشيطان إنه لكم عدو مبين","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން އެންމެން އިސްލާމް ދީނަށް ކިޔަމަންވުމުގެ ތެރެޔަށް ވަންނާށެވެ! އަދި ޝައިތާނާގެ ފިޔަވަޅުތަކަށް ތިޔަބައިމީހުން ތަބާ ނުވާށެވެ! އެހެނީ، ހަމަކަށަވަރުން އެ ޝައިތާނާ އަކީ ތިޔަ ބައިމީހުންނަށް ހުރި ބަޔާން ވެގެންވާ އަދުއްވެކެވެ.","",""],["₂ سورة البقرة","209","فَإِن زَلَلۡتُم مِّنۢ بَعۡدِ مَا جَآءَتۡكُمُ ٱلۡبَيِّنَٰتُ فَٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌ ٢٠٩","فإن زللتم من بعد ما جاءتكم البينات فاعلموا أن الله عزيز حكيم","ފަހެ، ތިޔަބައިމީހުންގެ ގާތަށް ފާޅުވެގެންހުރި ހުއްޖަތްތައް އައުމަށްފަހު ތިޔަބައިމީހުން މަގުން ކައްސާލައިގެން ހިނގައްޖެނަމަ، ހަމަކަށަވަރުން، ﷲއީ، ޢަޒީޒުވަންތަ ޙަކީމްވަންތަ ރަސްކަލާނގެކަން ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₂ سورة البقرة","210","هَلۡ يَنظُرُونَ إِلَّآ أَن يَأۡتِيَهُمُ ٱللَّهُ فِي ظُلَلٖ مِّنَ ٱلۡغَمَامِ وَٱلۡمَلَـٰٓئِكَةُ وَقُضِيَ ٱلۡأَمۡرُۚ وَإِلَى ٱللَّهِ تُرۡجَعُ ٱلۡأُمُورُ ٢١٠","هل ينظرون إلا أن يأتيهم الله في ظلل من الغمام والملائكة وقضي الأمر وإلى الله ترجع الأمور","ތުނި ވިލާތަކުގެ ހިޔާތަކެއްގެ ތެރެއިން ﷲއާއި މަލާއިކަތުން އެއުރެންގެ ގާތަށް ވަޑައިގަތުމަށް މެނުވީ، އެއުރެން ބަލަބަލައި ނުތިބެނީ ހެއްޔެވެ؟ އެހިނދު ނިޔާކަނޑައެޅި ނިމިއްޖެއެވެ. ހުރިހާ ކަމެއްގެ ނިޔާ އެނބުރި ދާހުށީ، ﷲގެ ހަޒުރަތަށެވެ.","",""],["₂ سورة البقرة","211","سَلۡ بَنِيٓ إِسۡرَـٰٓءِيلَ كَمۡ ءَاتَيۡنَٰهُم مِّنۡ ءَايَةِۭ بَيِّنَةٖۗ وَمَن يُبَدِّلۡ نِعۡمَةَ ٱللَّهِ مِنۢ بَعۡدِ مَا جَآءَتۡهُ فَإِنَّ ٱللَّهَ شَدِيدُ ٱلۡعِقَابِ ٢١١","سل بني إسرائيل كم آتيناهم من آية بينة ومن يبدل نعمة الله من بعد ما جاءته فإن الله شديد العقاب","ބަޔާން ވެގެންހުރި ހެކިތަކުގެ ތެރެއިން ކިތައް ކިތައް ކަންތައް ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްވާފައިވޭތޯ، ކަލޭގެފާނު އިސްރާއީލުގެދަރިންނާ ސުވާލުކުރައްވައި ބައްލަވާށެވެ! ﷲގެ ނިއުމަތް އެމީހަކަށް ލިބުމަށްފަހު، އެ ނިއުމަތް ބަދަލުކުރާ މީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، އުގޫބާތް ގަދަފަދަވެގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","212","زُيِّنَ لِلَّذِينَ كَفَرُواْ ٱلۡحَيَوٰةُ ٱلدُّنۡيَا وَيَسۡخَرُونَ مِنَ ٱلَّذِينَ ءَامَنُواْۘ وَٱلَّذِينَ ٱتَّقَوۡاْ فَوۡقَهُمۡ يَوۡمَ ٱلۡقِيَٰمَةِۗ وَٱللَّهُ يَرۡزُقُ مَن يَشَآءُ بِغَيۡرِ حِسَابٖ ٢١٢","زين للذين كفروا الحياة الدنيا ويسخرون من الذين آمنوا والذين اتقوا فوقهم يوم القيامة والله يرزق من يشاء بغير حساب","ކާފިރުވި މީސްތަކުންނަށް ދުނިޔޭގެ ދިރިއުޅުން ޒީނަތްތެރި ކުރެއްވިއެވެ. އަދި އީމާންވި މީސްތަކުންނަށް އެއުރެން މަލާމާތްކޮށް އުޅެތެވެ. ތަގުވާވެރިވި މީހުން ގިޔާމަތް ދުވަހުން ވާހުށީ، އެއުރެންނަށްވުރެން މަތީގައެވެ. ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ވަކި މިންވަރެއްނެތި ރިޒްގު ދެއްވަތެވެ.","",""],["₂ سورة البقرة","213","كَانَ ٱلنَّاسُ أُمَّةٗ وَٰحِدَةٗ فَبَعَثَ ٱللَّهُ ٱلنَّبِيِّـۧنَ مُبَشِّرِينَ وَمُنذِرِينَ وَأَنزَلَ مَعَهُمُ ٱلۡكِتَٰبَ بِٱلۡحَقِّ لِيَحۡكُمَ بَيۡنَ ٱلنَّاسِ فِيمَا ٱخۡتَلَفُواْ فِيهِۚ وَمَا ٱخۡتَلَفَ فِيهِ إِلَّا ٱلَّذِينَ أُوتُوهُ مِنۢ بَعۡدِ مَا جَآءَتۡهُمُ ٱلۡبَيِّنَٰتُ بَغۡيَۢا بَيۡنَهُمۡۖ فَهَدَى ٱللَّهُ ٱلَّذِينَ ءَامَنُواْ لِمَا ٱخۡتَلَفُواْ فِيهِ مِنَ ٱلۡحَقِّ بِإِذۡنِهِۦۗ وَٱللَّهُ يَهۡدِي مَن يَشَآءُ إِلَىٰ صِرَٰطٖ مُّسۡتَقِيمٍ ٢١٣","كان الناس أمة واحدة فبعث الله النبيين مبشرين ومنذرين وأنزل معهم الكتاب بالحق ليحكم بين الناس فيما اختلفوا فيه وما اختلف فيه إلا الذين أوتوه من بعد ما جاءتهم البينات بغيا بينهم فهدى الله الذين آمنوا لما اختلفوا فيه من الحق بإذنه والله يهدي من يشاء إلى صراط مستقيم","މީސްތަކުން އެއް އުއްމަތެއްގެ ބަޔަކު ކަމުގައިވިއެވެ. ދެންފަހެ، ﷲ، އުފާވެރިކަމުގެ ޚަބަރު ދޭ ބަޔެއްގެ ގޮތުގައްޔާއި އަދި އިންޒާރުކުރަނިވި ބަޔެއްގެ ގޮތުގައި ނަބީބޭކަލުން ފޮނުއްވިއެވެ. އަދި މީސްތަކުން އެއުރެންގެ މެދުގައި ޚިލާފުވި ކަންތައްތަކުގައި ހުކުމްކުޅައުމަށް، އެބޭކަލުންނާ އެކުގައި ހައްގު ގޮތުގައި ފޮތް ބާވައިލެއްވިއެވެ. އެފޮތް ލިބިގެންވާ މީހުން މެނުވީ، އެ ފޮތާ މެދުގައި ޚިލާފެއް ނުވިއެވެ. (އެއީ) އެއުރެންގެ ގާތަށް ބަޔާން ވެގެންވާ ހެކިތައް އައުމަށްފަހުގައެވެ. އެއުރެންގެ މެދުގައިވާ އަދާވަތް ތެރި ކަމާއި ހަސަދަވެރި ކަމުގެ ގޮތުންނެވެ. ދެން އެއުރެން ޚިލާފު ވެފައިވާ ކަންތަކާމެދުގައި އީމާންވި މީސްތަކުންނަށް، ﷲ، އެކަލާނގެ އިޒުނަފުޅުން ހައްގު ތެދުމަގު ދެއްކެވިއެވެ. އަދި ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ ބަޔަކަށް ސީދާވެގެންވާ ތެދުމަގަށް މަގު ދައްކަވަތެވެ.","",""],["₂ سورة البقرة","214","أَمۡ حَسِبۡتُمۡ أَن تَدۡخُلُواْ ٱلۡجَنَّةَ وَلَمَّا يَأۡتِكُم مَّثَلُ ٱلَّذِينَ خَلَوۡاْ مِن قَبۡلِكُمۖ مَّسَّتۡهُمُ ٱلۡبَأۡسَآءُ وَٱلضَّرَّآءُ وَزُلۡزِلُواْ حَتَّىٰ يَقُولَ ٱلرَّسُولُ وَٱلَّذِينَ ءَامَنُواْ مَعَهُۥ مَتَىٰ نَصۡرُ ٱللَّهِۗ أَلَآ إِنَّ نَصۡرَ ٱللَّهِ قَرِيبٞ ٢١٤","أم حسبتم أن تدخلوا الجنة ولما يأتكم مثل الذين خلوا من قبلكم مستهم البأساء والضراء وزلزلوا حتى يقول الرسول والذين آمنوا معه متى نصر الله ألا إن نصر الله قريب","ތިޔަބައިމީހުންގެ ކުރީގައި އުޅެ ގޮސްފައިވާ މީހުންގެ ޙާލުތައް ތިޔަބައިމީހުންނާ ހަމަޔަށް އަދި ނައިސްވަނިކޮށް، ތިޔަބައިމީހުން ސުވަރުގެ ވަންނާނެކަމަށް ތިޔަބައިމީހުން ހީކުރީހެއްޔެވެ؟ އެއުރެންނަށް ތަދުމަޑުކަމާއި ބަލިމަޑުކަން ޖެހުނެވެ. އަދި އެއުރެންނަށް ގުޑުންއަރައިގެން ދިޔައެވެ. ރަސޫލާއާއި އެކަލޭގެފާނުގެ އަރިހުގައި ތިބި އީމާންވި މީސްތަކުންނަށް ބުނެވިއްޖައުމަށް ދާނދެނެވެ. ﷲގެ ނަސްރު އަންނާނީ، ދެން ކޮންއިރަކުން ބާވައެވެ؟ ދަންނާށެވެ! ހަމަކަށަވަރުން، ﷲގެ ނަސްރު ވަނީ ދާދި ގާތުގައެވެ.","",""],["₂ سورة البقرة","215","يَسۡـَٔلُونَكَ مَاذَا يُنفِقُونَۖ قُلۡ مَآ أَنفَقۡتُم مِّنۡ خَيۡرٖ فَلِلۡوَٰلِدَيۡنِ وَٱلۡأَقۡرَبِينَ وَٱلۡيَتَٰمَىٰ وَٱلۡمَسَٰكِينِ وَٱبۡنِ ٱلسَّبِيلِۗ وَمَا تَفۡعَلُواْ مِنۡ خَيۡرٖ فَإِنَّ ٱللَّهَ بِهِۦ عَلِيمٞ ٢١٥","يسألونك ماذا ينفقون قل ما أنفقتم من خير فللوالدين والأقربين واليتامى والمساكين وابن السبيل وما تفعلوا من خير فإن الله به عليم","މީސްތަކުން، އެއުރެން ހޭދަކުރަންވީ ކޮން އެއްޗެއްތޯ ކަލޭގެފާނާ ސުވާލުކުރެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން މުދަލުގެ ތެރެއިން ހޭދަކުރާ އެއްޗެއް ހޭދަކުރަންވީ، މައިންބަފައިންނަށާއި ގާތްތިމާގެ މީހުންނަށާއި ޔަތީމުންނަށާއި މިސްކީނުންނަށާއި (ޙާލުގައި ޖެހިފައިވާ) ދަތުރުވެރިންނަށެވެ. އަދި ތިޔަބައިމީހުން ކުރާ ކޮންމެ ހެޔޮކަމެއް ހަމަކަށަވަރުން، ﷲ މޮޅަށް ދެނެވޮޑިގެންވެއެވެ.","",""],["₂ سورة البقرة","216","كُتِبَ عَلَيۡكُمُ ٱلۡقِتَالُ وَهُوَ كُرۡهٞ لَّكُمۡۖ وَعَسَىٰٓ أَن تَكۡرَهُواْ شَيۡـٔٗا وَهُوَ خَيۡرٞ لَّكُمۡۖ وَعَسَىٰٓ أَن تُحِبُّواْ شَيۡـٔٗا وَهُوَ شَرّٞ لَّكُمۡۚ وَٱللَّهُ يَعۡلَمُ وَأَنتُمۡ لَا تَعۡلَمُونَ ٢١٦","كتب عليكم القتال وهو كره لكم وعسى أن تكرهوا شيئا وهو خير لكم وعسى أن تحبوا شيئا وهو شر لكم والله يعلم وأنتم لا تعلمون","ހަނގުރާމަކުރުން ތިޔަބައިމީހުންގެ މައްޗަށް ފަރުޟުކުރައްވައިފިއެވެ. އެއީ، (އެކަމަކީ) ތިޔަބައިމީހުންނަށް ނުރުހެވޭ ކަމެއް ކަމުގައި ވަނިކޮށެވެ. އަދި ތިޔަބައިމީހުން ނުރުހޭ ކަމެއް އެއީ ތިޔަބައިމީހުންނަށް ލާބަހުރި ކަމަކަށް ވެދާނެތެވެ. އަދި ތިޔަބައިމީހުން ރުހޭ ކަމެއް، އެއީ ތިޔަބައިމީހުންނަށް ގެއްލުންހުރި ކަމަކަށް ވެދާނެތެވެ. އަދި ﷲ ހުރިހާ ކަމެއްމެ ދެނެވޮޑިގެންވެއެވެ. ތިޔަބައިމީހުންނަކަށް ނޭނގެއެވެ.","",""],["₂ سورة البقرة","217","يَسۡـَٔلُونَكَ عَنِ ٱلشَّهۡرِ ٱلۡحَرَامِ قِتَالٖ فِيهِۖ قُلۡ قِتَالٞ فِيهِ كَبِيرٞۚ وَصَدٌّ عَن سَبِيلِ ٱللَّهِ وَكُفۡرُۢ بِهِۦ وَٱلۡمَسۡجِدِ ٱلۡحَرَامِ وَإِخۡرَاجُ أَهۡلِهِۦ مِنۡهُ أَكۡبَرُ عِندَ ٱللَّهِۚ وَٱلۡفِتۡنَةُ أَكۡبَرُ مِنَ ٱلۡقَتۡلِۗ وَلَا يَزَالُونَ يُقَٰتِلُونَكُمۡ حَتَّىٰ يَرُدُّوكُمۡ عَن دِينِكُمۡ إِنِ ٱسۡتَطَٰعُواْۚ وَمَن يَرۡتَدِدۡ مِنكُمۡ عَن دِينِهِۦ فَيَمُتۡ وَهُوَ كَافِرٞ فَأُوْلَـٰٓئِكَ حَبِطَتۡ أَعۡمَٰلُهُمۡ فِي ٱلدُّنۡيَا وَٱلۡأٓخِرَةِۖ وَأُوْلَـٰٓئِكَ أَصۡحَٰبُ ٱلنَّارِۖ هُمۡ فِيهَا خَٰلِدُونَ ٢١٧","يسألونك عن الشهر الحرام قتال فيه قل قتال فيه كبير وصد عن سبيل الله وكفر به والمسجد الحرام وإخراج أهله منه أكبر عند الله والفتنة أكبر من القتل ولا يزالون يقاتلونكم حتى يردوكم عن دينكم إن استطاعوا ومن يرتدد منكم عن دينه فيمت وهو كافر فأولئك حبطت أعمالهم في الدنيا والآخرة وأولئك أصحاب النار هم فيها خالدون","ހުރުމަތް ތެރިވެގެންވާ މައްސަރުގައި ހަނގުރާމަ ކުޅައުމަކީ ކޮންކަހަލަ ކަމެއްތޯ އެއުރެން ކަލޭގެފާނާ ސުވާލުކުރެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެ މައްސަރުގައި ހަނގުރާމަ ކުޅައުމަކީ ބޮޑުވެގެންވާ ފާފައެކެވެ. (އެކަމަކު) ﷲގެ މަގުން (މީސްތަކުން) ދުރުކުޅައުމާއި އެކަލާނގެއަށް ކާފިރު ވުމާއި ހުރުމަތް ތެރިވެގެންވާ މިސްކިތަށް ވަނަ ނުދިނުމާއި އެތާނގެ އަހުލުވެރިތަކުން އެތަނުން ނެރެލުމުގެ ފާފަވެރިކަން ﷲގެ ހަޒުރަތުގައި މާބޮޑެވެ. އަދި ގަތުލުކުރުމަށްވުރެ ފިތުނަވެރިކަމުގެ ނުބައިކަން މާބޮޑެވެ. އަދި އެއުރެންނަށް ކުޅަދާނަވެގެން ވަނީނަމަ، ތިޔަބައިމީހުންގެ ދީނުން ތިޔަބައިމީހުން ބޭރުކޮށް ކާފިރުކަމަށް ތިޔަބައިމީހުން ރައްދުކޮށްފުމަށް ދާނދެން ތިޔަބައިމީހުންނާ ހަނގުރާމަ ކުރުމުގައި އެއުރެން ފިލައިނުދާނެއެވެ. ތިޔަބައިމީހުންގެ ތެރެއިން މުރުތައްދުވެ، ކާފިރަކު ކަމުގައިވާ ޙާލު، މަރުވާ މީހުންނީ، ދުނިޔެއާއި އާޚިރަތުގައި އެއުރެންގެ ޢަމަލުތައް އުވިގޮސްފައިވާ ބަޔެކެވެ. އަދި އެއުރެންނީ، ނަރަކައިގެ އަހުލުވެރިންނެވެ. އެއުރެން ދެމިތިބޭނީ، އެތާނގައެވެ.","",""],["₂ سورة البقرة","218","إِنَّ ٱلَّذِينَ ءَامَنُواْ وَٱلَّذِينَ هَاجَرُواْ وَجَٰهَدُواْ فِي سَبِيلِ ٱللَّهِ أُوْلَـٰٓئِكَ يَرۡجُونَ رَحۡمَتَ ٱللَّهِۚ وَٱللَّهُ غَفُورٞ رَّحِيمٞ ٢١٨","إن الذين آمنوا والذين هاجروا وجاهدوا في سبيل الله أولئك يرجون رحمت الله والله غفور رحيم","ހަމަކަށަވަރުން އީމާންވި މީހުންނާއި، ހިޖުރަ ކޮށް، ﷲގެ މަގުގައި ޖިހާދުކުޅަ މީހުން، އެ މީސްމީހުން ﷲގެ ރަހުމަތަށް އެދެތެވެ. ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","219","۞يَسۡـَٔلُونَكَ عَنِ ٱلۡخَمۡرِ وَٱلۡمَيۡسِرِۖ قُلۡ فِيهِمَآ إِثۡمٞ كَبِيرٞ وَمَنَٰفِعُ لِلنَّاسِ وَإِثۡمُهُمَآ أَكۡبَرُ مِن نَّفۡعِهِمَاۗ وَيَسۡـَٔلُونَكَ مَاذَا يُنفِقُونَۖ قُلِ ٱلۡعَفۡوَۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمُ ٱلۡأٓيَٰتِ لَعَلَّكُمۡ تَتَفَكَّرُونَ ٢١٩","يسألونك عن الخمر والميسر قل فيهما إثم كبير ومنافع للناس وإثمهما أكبر من نفعهما ويسألونك ماذا ينفقون قل العفو كذلك يبين الله لكم الآيات لعلكم تتفكرون","ރާއާއި ޖުވާކުޅުމާމެދު އެއުރެން ކަލޭގެފާނާ ސުވާލުކުރެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެ ދެކަމުގައި ބޮޑުވެގެންވާ ފާފަވެރިވުމަކާއި މީސްތަކުންނަށް ހިސާބަކަށް ނަފާ ލިބެނިވި ގޮތްތަކެއްވެސް ވެއެވެ. އެ ދެކަމުގެ މަންފާއަށްވުރެ، އެ ދެކަމުގެ ފާފަވެރިކަން މާބޮޑެވެ. އަދި އެއުރެން ހޭދަކުރަންވީ ކޮންއެއްޗެއްތޯ ކަލޭގެފާނާ އެއުރެން ސުވާލުކުރެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! (ހޭދަކުރަންވީ) އިތުރުވީ އެއްޗެކެވެ. އެފަދައިން ތިޔަބައިމީހުންނަށް ﷲ، (އެކަލާނގެ) ހުކުމްތައް ބަޔާން ކޮށްދެއްވަނީ، ތިޔަބައިމީހުން ފިކުރުކުޅައުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","220","فِي ٱلدُّنۡيَا وَٱلۡأٓخِرَةِۗ وَيَسۡـَٔلُونَكَ عَنِ ٱلۡيَتَٰمَىٰۖ قُلۡ إِصۡلَاحٞ لَّهُمۡ خَيۡرٞۖ وَإِن تُخَالِطُوهُمۡ فَإِخۡوَٰنُكُمۡۚ وَٱللَّهُ يَعۡلَمُ ٱلۡمُفۡسِدَ مِنَ ٱلۡمُصۡلِحِۚ وَلَوۡ شَآءَ ٱللَّهُ لَأَعۡنَتَكُمۡۚ إِنَّ ٱللَّهَ عَزِيزٌ حَكِيمٞ ٢٢٠","في الدنيا والآخرة ويسألونك عن اليتامى قل إصلاح لهم خير وإن تخالطوهم فإخوانكم والله يعلم المفسد من المصلح ولو شاء الله لأعنتكم إن الله عزيز حكيم","(ފިކުރުކުރަންވީ) ދުނިޔެއާއި އާޚިރަތާ މެދުގައެވެ. އަދި ޔަތީމުންނާ މެދުގައި އެއުރެން ކަލޭގެފާނާ ސުވާލުކުރެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއުރެންގެ ކަންތައްތައް އިސްލާހުކުރުމީ ހެޔޮކަން ބޮޑުވެގެންވާ ކަމެކެވެ. އަދި ތިޔަބައިމީހުން އެއުރެންނާ ގުޅިގެން އުޅޭނަމަ އެއުރެންނީވެސް ތިޔަބައިމީހުންގެ އަޚުންނެވެ. އަދި އިސްލާހުކުރާ މީހުންނާއި ފަސާދަކުރާ މީހުން، ﷲ ދެނެވޮޑިގެންވެއެވެ. ﷲ އިރާދަކުރައްވައިފިނަމަ، ތިޔަބައިމީހުންނަށް ދަތިކުރައްވައިފީހެވެ. ހަމަކަށަވަރުން ﷲއީ، ޢަޒީޒުވަންތަ ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","221","وَلَا تَنكِحُواْ ٱلۡمُشۡرِكَٰتِ حَتَّىٰ يُؤۡمِنَّۚ وَلَأَمَةٞ مُّؤۡمِنَةٌ خَيۡرٞ مِّن مُّشۡرِكَةٖ وَلَوۡ أَعۡجَبَتۡكُمۡۗ وَلَا تُنكِحُواْ ٱلۡمُشۡرِكِينَ حَتَّىٰ يُؤۡمِنُواْۚ وَلَعَبۡدٞ مُّؤۡمِنٌ خَيۡرٞ مِّن مُّشۡرِكٖ وَلَوۡ أَعۡجَبَكُمۡۗ أُوْلَـٰٓئِكَ يَدۡعُونَ إِلَى ٱلنَّارِۖ وَٱللَّهُ يَدۡعُوٓاْ إِلَى ٱلۡجَنَّةِ وَٱلۡمَغۡفِرَةِ بِإِذۡنِهِۦۖ وَيُبَيِّنُ ءَايَٰتِهِۦ لِلنَّاسِ لَعَلَّهُمۡ يَتَذَكَّرُونَ ٢٢١","ولا تنكحوا المشركات حتى يؤمن ولأمة مؤمنة خير من مشركة ولو أعجبتكم ولا تنكحوا المشركين حتى يؤمنوا ولعبد مؤمن خير من مشرك ولو أعجبكم أولئك يدعون إلى النار والله يدعو إلى الجنة والمغفرة بإذنه ويبين آياته للناس لعلهم يتذكرون","ބުދަށް އަޅުކަންކުރާ އަންހެނުންނާ ތިޔަބައިމީހުން ކާވެނި ނުކުރާށެވެ! (އެއީ) އެކަނބަލުން އީމާން ވެއްޖައުމަށް ދާނދެނެވެ. ތިޔަބައިމީހުން ހިތާވާ ކަމުގައިވިޔަސް ހަމަކަށަވަރުން މުއުމިނު އަޅުއަންހެނަކުވެސް، ބުދަށް އަޅުކަންކުރާ އަންހެނަކަށްވުރެ މާރަނގަޅެވެ. އަދި (މުއުމިނު އަންހެނުން) ބުދަށް އަޅުކަންކުރާ ފިރިހެނުންނާތިޔަބައިމީހުން ނުދެވާށެވެ! (އެއީ) އެއުރެން އީމާން ވެއްޖައުމަށް ދާނދެނެވެ. ތިޔަބައިމީހުން އެމީހަކާ ރުހި ގަބޫލު ވިޔަސް، ހަމަކަށަވަރުން މުއުމިނު ފިރިހެން އަޅަކުވެސް ބުދަށް އަޅުކަންކުރާ ފިރިހެނަކަށްވުރެ މާރަނގަޅެވެ. އެއުރެން އެ ގޮވަނީ ނަރަކަޔަށް ވަނުމަށެވެ. ﷲ ގޮވައިލައްވަނީ އެކަލާނގެ އިރާދަފުޅުން ތިޔަބައިމީހުން ސުވަރުގެއަށާއި މަޣުފިރަތްގެ ތެރެއަށް ވަނުމަށެވެ. އަދި އެކަލާނގެ އާޔަތްތައް މީސްތަކުންނަށް ބަޔާންކޮށްދެއްވަނީ އެއުރެން ހަނދުމަކުރުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","222","وَيَسۡـَٔلُونَكَ عَنِ ٱلۡمَحِيضِۖ قُلۡ هُوَ أَذٗى فَٱعۡتَزِلُواْ ٱلنِّسَآءَ فِي ٱلۡمَحِيضِ وَلَا تَقۡرَبُوهُنَّ حَتَّىٰ يَطۡهُرۡنَۖ فَإِذَا تَطَهَّرۡنَ فَأۡتُوهُنَّ مِنۡ حَيۡثُ أَمَرَكُمُ ٱللَّهُۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلتَّوَّـٰ‌بِينَ وَيُحِبُّ ٱلۡمُتَطَهِّرِينَ ٢٢٢","ويسألونك عن المحيض قل هو أذى فاعتزلوا النساء في المحيض ولا تقربوهن حتى يطهرن فإذا تطهرن فأتوهن من حيث أمركم الله إن الله يحب التوابين ويحب المتطهرين","އަދި ހައިޟާމެދު، ކަލޭގެފާނާ އެއުރެން ސުވާލުކުރެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއީ އުނދަގޫ (ލިބެނިވި) ކަމެކެވެ. ފަހެ، ހައިޟުގެ ދުވަސްވަރުގައި ތިޔަބައިމީހުން އަންހެނުންނާ ދުރުހެލިވާށެވެ! (އެބަހީ: ޖިމާއު ނުވާށެވެ!) އަދި އެކަނބަލުން ހިނައި ތާހިރު ވެއްޖައުމަށްދާނދެން ތިޔަބައިމީހުން އެކަނބަލުންނާ ގާތްނުވާށެވެ! ފަހެ އެކަނބަލުން ހިނައި ތާހިރު ވެއްޖެނަމަ، ﷲ ތިޔަބައިމީހުންނަށް އަމުރުކުރައްވާފައިވާ ފަދައިން އެކަނބަލުން ގާތަށް ތިޔަބައިމީހުން ދާށެވެ! (އެބަހީ: ޖިމާއު ވުން ހުއްދައެވެ.) ހަމަކަށަވަރުން، ގިނަގިނައިން ތައުބާވާ މީހުންދެކެ ﷲ ލޯބިވެ ވޮޑިގެންވެއެވެ. އަދި ތާހިރުވާ މީހުން ދެކެވެސް އެކަލާނގެ ލޯބިވެވޮޑިގެންވެއެވެ.","",""],["₂ سورة البقرة","223","نِسَآؤُكُمۡ حَرۡثٞ لَّكُمۡ فَأۡتُواْ حَرۡثَكُمۡ أَنَّىٰ شِئۡتُمۡۖ وَقَدِّمُواْ لِأَنفُسِكُمۡۚ وَٱتَّقُواْ ٱللَّهَ وَٱعۡلَمُوٓاْ أَنَّكُم مُّلَٰقُوهُۗ وَبَشِّرِ ٱلۡمُؤۡمِنِينَ ٢٢٣","نساؤكم حرث لكم فأتوا حرثكم أنى شئتم وقدموا لأنفسكم واتقوا الله واعلموا أنكم ملاقوه وبشر المؤمنين","ތިޔަބައިމީހުންގެ އަނބިންނީ، ތިޔަބައިމީހުންނަށްވާ ދަނޑުބިމެކެވެ. ފަހެ ތިޔަބައިމީހުން ބޭނުންފަދައަކުން ތިޔަބައިމީހުންގެ ދަނޑުބިމަށް އަންނާށެވެ! (އެބަހީ: ނަސްލު އުފެދުމުގެ މަގު ޚިޔާރުކުރާށެވެ.) އަދި ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސު ތަކަށްޓަކައި (ހެޔޮކަންތައް) އިސްކުރާށެވެ! އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނީ އެކަލާނގެއާ ބައްދަލުވާނޭ ބަޔަކުކަން ތިޔަބައިމީހުން ދަންނާށެވެ! އަދި މުއުމިނު ތަކުންނަށް ކަލޭގެފާނު އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާށެވެ.","",""],["₂ سورة البقرة","224","وَلَا تَجۡعَلُواْ ٱللَّهَ عُرۡضَةٗ لِّأَيۡمَٰنِكُمۡ أَن تَبَرُّواْ وَتَتَّقُواْ وَتُصۡلِحُواْ بَيۡنَ ٱلنَّاسِۚ وَٱللَّهُ سَمِيعٌ عَلِيمٞ ٢٢٤","ولا تجعلوا الله عرضة لأيمانكم أن تبروا وتتقوا وتصلحوا بين الناس والله سميع عليم","ތިޔަބައިމީހުންގެ ހުވާތަކުން ތިޔަބައިމީހުން ހެޔޮކަންތައް ކުރުމަށާއި، ތަގުވާވެރިވުމަށާއި، މީސްތަކުންގެ މެދުގައި ސުލްހަ މަސަލަސްކަން ގާއިމުކުޅައުމަށް އެޅޭ ހުރަހެއްކަމުގައި، ﷲގެ ނަންފުޅު ތިޔަބައިމީހުން ނުލާށެވެ! ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","225","لَّا يُؤَاخِذُكُمُ ٱللَّهُ بِٱللَّغۡوِ فِيٓ أَيۡمَٰنِكُمۡ وَلَٰكِن يُؤَاخِذُكُم بِمَا كَسَبَتۡ قُلُوبُكُمۡۗ وَٱللَّهُ غَفُورٌ حَلِيمٞ ٢٢٥","لا يؤاخذكم الله باللغو في أيمانكم ولكن يؤاخذكم بما كسبت قلوبكم والله غفور حليم","ތިޔަބައިމީހުންގެ ހުވާތަކުގައި، ގަސްދަކާ ނުލައި ބުނާ ބަސްތަކަކުން ﷲ ތިޔަބައިމީހުންނަށް އުގޫބާތެއް ނުދެއްވާނެއެވެ. އެހެނެއްކަމަކު ތިޔަބައިމީހުން ހިތުގެ ގަސްދާއެކު ކުރާ ހުވަޔަށް (އެ ހުވަޔާ ޚިލާފު ވެއްޖެނަމަ) އެކަލާނގެ ތިޔަބައިމީހުންނަށް އުގޫބާތް ދެއްވާނެއެވެ. ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ހަލީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","226","لِّلَّذِينَ يُؤۡلُونَ مِن نِّسَآئِهِمۡ تَرَبُّصُ أَرۡبَعَةِ أَشۡهُرٖۖ فَإِن فَآءُو فَإِنَّ ٱللَّهَ غَفُورٞ رَّحِيمٞ ٢٢٦","للذين يؤلون من نسائهم تربص أربعة أشهر فإن فاءوا فإن الله غفور رحيم","އެއުރެންގެ އަނބިންނާމެދު (ޖިމާއު ނުވުމަށް) ހުވާކުރާ މީހުންނަށް އިންތިޒާރުކުރުން ވަނީ، ހަތަރު މަސްދުވަހަށެވެ. ފަހެ، އެއުރެން (ޖިމާއު ވުމަށް) އެނބުރި ރުޖޫއަ ވެއްޖެނަމަ، ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","227","وَإِنۡ عَزَمُواْ ٱلطَّلَٰقَ فَإِنَّ ٱللَّهَ سَمِيعٌ عَلِيمٞ ٢٢٧","وإن عزموا الطلاق فإن الله سميع عليم","އަދި، އެއުރެން ވަރިކުރުމަށް ގަސްދު ކޮށްފިނަމަ، ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","228","وَٱلۡمُطَلَّقَٰتُ يَتَرَبَّصۡنَ بِأَنفُسِهِنَّ ثَلَٰثَةَ قُرُوٓءٖۚ وَلَا يَحِلُّ لَهُنَّ أَن يَكۡتُمۡنَ مَا خَلَقَ ٱللَّهُ فِيٓ أَرۡحَامِهِنَّ إِن كُنَّ يُؤۡمِنَّ بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِۚ وَبُعُولَتُهُنَّ أَحَقُّ بِرَدِّهِنَّ فِي ذَٰلِكَ إِنۡ أَرَادُوٓاْ إِصۡلَٰحٗاۚ وَلَهُنَّ مِثۡلُ ٱلَّذِي عَلَيۡهِنَّ بِٱلۡمَعۡرُوفِۚ وَلِلرِّجَالِ عَلَيۡهِنَّ دَرَجَةٞۗ وَٱللَّهُ عَزِيزٌ حَكِيمٌ ٢٢٨","والمطلقات يتربصن بأنفسهن ثلاثة قروء ولا يحل لهن أن يكتمن ما خلق الله في أرحامهن إن كن يؤمن بالله واليوم الآخر وبعولتهن أحق بردهن في ذلك إن أرادوا إصلاحا ولهن مثل الذي عليهن بالمعروف وللرجال عليهن درجة والله عزيز حكيم","އަދި، ވަރިކޮށްފައިވާ އަންހެނުން، އެކަނބަލުންގެ އަމިއްލަ ނަފްސު ތަކާއިގެން ތިން ގުރުއު ވަންދެން އިންތިޒާރުކުރާހުށިކަމެވެ! (ގުރުއަކީ، ހައިޟު ނުވަތަ ތުހުރެވެ.) އަދި، އެކަނބަލުން، ﷲއަށާއި، އާޚިރަތް ދުވަހަށް، އީމާންވާ ކަމުގައިވާނަމަ، އެކަނބަލުންގެ ރަޙިމު ތަކުގައި ﷲ އުފައްދަވާފައިވާ އެއްޗެއް (އެބަހީ: ހައިޟު ވުމާއި ބަލިވެއިނުންފަދަ ކަންތައް) ވަންހަނާކުރުން އެކަނބަލުންނަށް ހުއްދައެއް ނުވާނެތެވެ. އަދި، އެއުރެން އިސްލާހުކުރުމަށް އެދޭނަމަ، އިއްދަގެ ދުވަސްވަރުގައި އެކަނބަލުން ކާވެންޏަށް އަނބުރައި ގެނައުން އެކަނބަލުންގެ ފިރީންނަށް ހައްގު ވެގެން ވެއެވެ. އަދި ޝަރުއީ ހަމައިން (ފިރިންނަށް އަދާކުރުން) އެކަނބަލުންގެ މައްޗަށް ވާޖިބުވެގެންވާފަދަ ކަންތައްތައް (ފިރިންގެ ފަރާތުން) އެކަނބަލުންނަށްވެސް ހައްގު ވެގެން ވެއެވެ. އަދި އެކަނބަލުންގެ މައްޗަށް ފިރިހެނުންނަށް ދަރަޖައެއް ލިބިގެންވެއެވެ. ﷲއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","229","ٱلطَّلَٰقُ مَرَّتَانِۖ فَإِمۡسَاكُۢ بِمَعۡرُوفٍ أَوۡ تَسۡرِيحُۢ بِإِحۡسَٰنٖۗ وَلَا يَحِلُّ لَكُمۡ أَن تَأۡخُذُواْ مِمَّآ ءَاتَيۡتُمُوهُنَّ شَيۡـًٔا إِلَّآ أَن يَخَافَآ أَلَّا يُقِيمَا حُدُودَ ٱللَّهِۖ فَإِنۡ خِفۡتُمۡ أَلَّا يُقِيمَا حُدُودَ ٱللَّهِ فَلَا جُنَاحَ عَلَيۡهِمَا فِيمَا ٱفۡتَدَتۡ بِهِۦۗ تِلۡكَ حُدُودُ ٱللَّهِ فَلَا تَعۡتَدُوهَاۚ وَمَن يَتَعَدَّ حُدُودَ ٱللَّهِ فَأُوْلَـٰٓئِكَ هُمُ ٱلظَّـٰلِمُونَ ٢٢٩","الطلاق مرتان فإمساك بمعروف أو تسريح بإحسان ولا يحل لكم أن تأخذوا مما آتيتموهن شيئا إلا أن يخافا ألا يقيما حدود الله فإن خفتم ألا يقيما حدود الله فلا جناح عليهما فيما افتدت به تلك حدود الله فلا تعتدوها ومن يتعد حدود الله فأولئك هم الظالمون","ވަރިކުރުން އޮތީ ދެފަހަރުއެވެ. ދެންއޮތީ ހެޔޮގޮތުގައި (އެކަނބަލުންނާ) އިނދެގެން އުޅުމެވެ. ނުވަތަ ހެޔޮކޮށް ހިތުމާއެކު (އެކަނބަލުން) ދޫކޮށްލުމެވެ. އަދި، އެ ދެމީހުން، ﷲ ކަނޑައަޅުއްވާފައިވާ ހުކުމްތައް ގާއިމު ނުކުރެވިދާނެކަމަށް ބިރުގަންނަނަމަ މެނުވީ، އެކަނބަލުންނަށް ތިޔަބައިމީހުން ދީފައިވާ ތަކެތީގެ ތެރެއިން އެއްޗެއް ތިޔަބައިމީހުން އަތުލުން ތިޔަބައިމީހުންނަކަށް ހަލާލު ވެގެނެއް ނުވެއެވެ. ﷲ ކަނޑައަޅުއްވާފައިވާ ހުކުމްތައް އެ ދެމީހުންނަށް ގާއިމު ނުކުރެވޭނެކަމަށް ތިޔަބައިމީހުން ބިރުގަންނަނަމަ، ފަހެ، އެކަނބުލޭގެ ވަރިވުމަށް އެއްޗެއްދިނުމާއި، ދިންއެއްޗެއް ހިފުމުގައި، އެ ދެމީހުންގެ މައްޗަކަށް ކުށެއްނެތެވެ. އެއީ (އެކަންކަމާމެދު) ﷲ ކަނޑައަޅުއްވާފައިވާ އިންތަކެވެ. ފަހެ، އެ އިންތައް ފަހަނަޅައި ތިޔަބައިމީހުން ނުދާށެވެ! އަދި ﷲ ކަނޑައަޅުއްވާފައިވާ އިންތައް ފަހަނަޅައިދާ މީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ ހަމަ އަނިޔާވެރިންނެވެ.","",""],["₂ سورة البقرة","230","فَإِن طَلَّقَهَا فَلَا تَحِلُّ لَهُۥ مِنۢ بَعۡدُ حَتَّىٰ تَنكِحَ زَوۡجًا غَيۡرَهُۥۗ فَإِن طَلَّقَهَا فَلَا جُنَاحَ عَلَيۡهِمَآ أَن يَتَرَاجَعَآ إِن ظَنَّآ أَن يُقِيمَا حُدُودَ ٱللَّهِۗ وَتِلۡكَ حُدُودُ ٱللَّهِ يُبَيِّنُهَا لِقَوۡمٖ يَعۡلَمُونَ ٢٣٠","فإن طلقها فلا تحل له من بعد حتى تنكح زوجا غيره فإن طلقها فلا جناح عليهما أن يتراجعا إن ظنا أن يقيما حدود الله وتلك حدود الله يبينها لقوم يعلمون","ދެން (ތިންވަނަ ފަހަރަށް) އެކަނބުލޭގެ ވަރިކޮށްފިނަމަ، އެއަށްފަހު، އެކަނބުލޭގެ އެހެން ފިރިޔަކާ ކާވެނިކޮށްފުމަށް ދާނދެން އޭނާއަކަށް (އެބަހީ: ތިންފަށްކުޅަ ފިރިޔާއަށް) އެކަނބުލޭގެ ހަލާލެއް ނުވާނެތެވެ. ދެން (ފަހުން އިން) ފިރިމީހާ، އެ އަންހެނާ ވަރިކޮށްފިނަމަ، (ކުރިން ވަރިކުރި) ފިރިހެނާއާއި، އެ އަންހެންމީހާއާއި، ދެމީހުން އަލުން އިނުމުގައި އެ ދެމީހުންގެ މައްޗަކަށް ކުށެއްނެތެވެ. އެއީ ﷲ އަންގަވާފައިވާ ހުކުމްތައް ގާއިމު ކޮށްގެން އުޅެވިދާނެކަމަށް އެ ދެމީހުންނަށް ހީވާނަމައެވެ. އަދި، އެއީ (މިކަމާމެދު) ﷲ ކަނޑައަޅުއްވާފައިވާ ހުކުމް ތަކެވެ. އެ ހުކުމްތައް އެކަލާނގެ ބަޔާންކޮށްދެއްވަނީ (އެ ހުކުމްތައް) ދެނެގަންނާނޭ ބަޔަކަށެވެ.","",""],["₂ سورة البقرة","231","وَإِذَا طَلَّقۡتُمُ ٱلنِّسَآءَ فَبَلَغۡنَ أَجَلَهُنَّ فَأَمۡسِكُوهُنَّ بِمَعۡرُوفٍ أَوۡ سَرِّحُوهُنَّ بِمَعۡرُوفٖۚ وَلَا تُمۡسِكُوهُنَّ ضِرَارٗا لِّتَعۡتَدُواْۚ وَمَن يَفۡعَلۡ ذَٰلِكَ فَقَدۡ ظَلَمَ نَفۡسَهُۥۚ وَلَا تَتَّخِذُوٓاْ ءَايَٰتِ ٱللَّهِ هُزُوٗاۚ وَٱذۡكُرُواْ نِعۡمَتَ ٱللَّهِ عَلَيۡكُمۡ وَمَآ أَنزَلَ عَلَيۡكُم مِّنَ ٱلۡكِتَٰبِ وَٱلۡحِكۡمَةِ يَعِظُكُم بِهِۦۚ وَٱتَّقُواْ ٱللَّهَ وَٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ بِكُلِّ شَيۡءٍ عَلِيمٞ ٢٣١","وإذا طلقتم النساء فبلغن أجلهن فأمسكوهن بمعروف أو سرحوهن بمعروف ولا تمسكوهن ضرارا لتعتدوا ومن يفعل ذلك فقد ظلم نفسه ولا تتخذوا آيات الله هزوا واذكروا نعمت الله عليكم وما أنزل عليكم من الكتاب والحكمة يعظكم به واتقوا الله واعلموا أن الله بكل شيء عليم","ތިޔަބައިމީހުންގެ އަނބިން ވަރިކޮށް އެކަނބަލުންގެ އިއްދަ ހަމަވާން ގާތްވެއްޖެނަމަ، ހެޔޮގޮތުގައި ތިޔަބައިމީހުން އެކަނބަލުން (ރުޖޫއަ ކޮށް) ހިފަހައްޓާށެވެ! ނުވަތަ، ހެޔޮގޮތުގައި އެކަނބަލުން ދޫކޮށްލާށެވެ! އަދި، ގެއްލުންދިނުމުގެ ގޮތުން އަނިޔާވެރިވުމަށްޓަކައި އެކަނބަލުން ނުހިފަހައްޓާށެވެ! އަދި، އެކަން އެގޮތަށް ކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާގެ އަމިއްލަ ނަފްސަށް އަނިޔާކޮށްފިކަން ކަށަވަރެވެ. އަދި، ﷲގެ އާޔަތްތައް އެއީ ފުރައްސާރައެއްކަމުގައި ތިޔަބައިމީހުން ނަހަދާށެވެ! އަދި، ތިޔަބައިމީހުންނަށް ﷲ ދެއްވި ނިއުމަތާއި، އަދި، ފޮތާއި، ހިކުމަތްގެ ތެރެއިން ތިޔަބައިމީހުންނަށް ބާވައިލެއްވި ތަކެތި، ތިޔަބައިމީހުން ހަނދުމަކުރާށެވެ! އެކަލާނގެ އެއިން ތިޔަބައިމީހުންނަށް ނަސޭހަތް ވަހީކުރައްވައެވެ. އަދި، ތިޔަބައިމީހުން، ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި، ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެކަން ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₂ سورة البقرة","232","وَإِذَا طَلَّقۡتُمُ ٱلنِّسَآءَ فَبَلَغۡنَ أَجَلَهُنَّ فَلَا تَعۡضُلُوهُنَّ أَن يَنكِحۡنَ أَزۡوَٰجَهُنَّ إِذَا تَرَٰضَوۡاْ بَيۡنَهُم بِٱلۡمَعۡرُوفِۗ ذَٰلِكَ يُوعَظُ بِهِۦ مَن كَانَ مِنكُمۡ يُؤۡمِنُ بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِۗ ذَٰلِكُمۡ أَزۡكَىٰ لَكُمۡ وَأَطۡهَرُۚ وَٱللَّهُ يَعۡلَمُ وَأَنتُمۡ لَا تَعۡلَمُونَ ٢٣٢","وإذا طلقتم النساء فبلغن أجلهن فلا تعضلوهن أن ينكحن أزواجهن إذا تراضوا بينهم بالمعروف ذلك يوعظ به من كان منكم يؤمن بالله واليوم الآخر ذلكم أزكى لكم وأطهر والله يعلم وأنتم لا تعلمون","އަދި، ތިޔަބައިމީހުންގެ އަނބިން ވަރިކޮށް އެކަނބަލުންގެ އިއްދަ ހަމަވެއްޖެނަމަ، އެކަނބަލުންގެ ފިރީންނާ، އެކަނބަލުން ކާވެނިކުރުމަށް ހުރަސް ނާޅާށެވެ! އެއީ، ހެޔޮގޮތުގައި، (އިނދެގެން އުޅުމަށް) އެއުރެންގެ މެދުގައި، ރުހި އެއްބަސް ވެއްޖެނަމައެވެ. ތިޔަބައިމީހުންކުރެ، ﷲއަށާއި، އާޚިރަތް ދުވަހަށް އީމާންވާ މީހުންނަށް ނަސޭހަތް ދެއްވާފައިވާގޮތަކީ އެއީއެވެ. ތިޔަބައިމީހުންނަށް އެންމެ ފައިދާހުރި، އަދި، ތާހިރު ކަންބޮޑު ގޮތަކީވެސް އެއީމެއެވެ. (ތިޔަބައިމީހުންނަށް މަސްލަތު ހުރިގޮތް) ﷲ ދެނެވޮޑިގެންވެއެވެ. ތިޔަބައިމީހުންނަކަށް ނޭނގެތެވެ.","",""],["₂ سورة البقرة","233","۞وَٱلۡوَٰلِدَٰتُ يُرۡضِعۡنَ أَوۡلَٰدَهُنَّ حَوۡلَيۡنِ كَامِلَيۡنِۖ لِمَنۡ أَرَادَ أَن يُتِمَّ ٱلرَّضَاعَةَۚ وَعَلَى ٱلۡمَوۡلُودِ لَهُۥ رِزۡقُهُنَّ وَكِسۡوَتُهُنَّ بِٱلۡمَعۡرُوفِۚ لَا تُكَلَّفُ نَفۡسٌ إِلَّا وُسۡعَهَاۚ لَا تُضَآرَّ وَٰلِدَةُۢ بِوَلَدِهَا وَلَا مَوۡلُودٞ لَّهُۥ بِوَلَدِهِۦۚ وَعَلَى ٱلۡوَارِثِ مِثۡلُ ذَٰلِكَۗ فَإِنۡ أَرَادَا فِصَالًا عَن تَرَاضٖ مِّنۡهُمَا وَتَشَاوُرٖ فَلَا جُنَاحَ عَلَيۡهِمَاۗ وَإِنۡ أَرَدتُّمۡ أَن تَسۡتَرۡضِعُوٓاْ أَوۡلَٰدَكُمۡ فَلَا جُنَاحَ عَلَيۡكُمۡ إِذَا سَلَّمۡتُم مَّآ ءَاتَيۡتُم بِٱلۡمَعۡرُوفِۗ وَٱتَّقُواْ ٱللَّهَ وَٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ بِمَا تَعۡمَلُونَ بَصِيرٞ ٢٣٣","والوالدات يرضعن أولادهن حولين كاملين لمن أراد أن يتم الرضاعة وعلى المولود له رزقهن وكسوتهن بالمعروف لا تكلف نفس إلا وسعها لا تضار والدة بولدها ولا مولود له بولده وعلى الوارث مثل ذلك فإن أرادا فصالا عن تراض منهما وتشاور فلا جناح عليهما وإن أردتم أن تسترضعوا أولادكم فلا جناح عليكم إذا سلمتم ما آتيتم بالمعروف واتقوا الله واعلموا أن الله بما تعملون بصير","މައިން، އެކަނބަލުންގެ ދަރިންނަށް ކިރުދޭހުށީ، ފުރިހަމަ ދެއަހަރުގެ މުއްދަތަށެވެ. އެއީ، ކިރުދިނުން ފުރިހަމަކުރުމަށް ގަސްދު ކޮށްފި މީހަކަށެވެ. އަދި އެކަށީގެންވާ ހެޔޮގޮތުގައި އެކަނބަލުންނަށް ކާންދިނުމާއި، އަންނައުނުދިނުން އެއީ، (ކުއްޖާގެ) ބަފާގެ މައްޗަށް ވާޖިބުވެގެންވާ ކަމެކެވެ. އެއްވެސް ނަފްސަކަށް، އެ ނަފްސަކަށް ކުޅަދާނަވެގެންވާ މިންވަރަކަށް މެނުވީ، ތަކުލީފެއް ނުޖައްސަވަތެވެ. މައިމީހާއަށް، އެކަނބުލޭގެ ދަރީގެ ސަބަބުން ގެއްލުމެއް ދީގެން ނުވާނެތެވެ. އަދި، ބަފަޔަކަށްވެސް، އޭނާގެ ދަރީގެ ސަބަބުން ގެއްލުމެއް ދީގެން ނުވާނެތެވެ. އަދި، (ކުއްޖާގެ ބަފާގެ މައްޗަށް ލާޒިމް ވީ ކަންތައް) ވާރުތަވެރިޔާގެ މައްޗަށްވެސް އެފަދައިން ލާޒިމް ވެގެންވެތެވެ. ފަހެ، އެ ދެމީހުންގެ ރުހުމާއި، މަޝްވަރާއާއެކު (ދެއަހަރު ހަމަވުމުގެ ކުރީގައި) ކިރުދިނުން ހުއްޓާލަން ގަސްދު ކޮށްފިނަމަ، (އެކަމުގައި) އެ ދެމީހުންގެ މައްޗަކަށް ކުށެއްނެތެވެ. އަދި، ތިޔަބައިމީހުންގެ ދަރިންނަށް އެހެން މީހަކު ލައްވާ ކިރުދިނުމަށް ގަސްދު ކޮށްފިނަމަ، ހެޔޮގޮތުގައި އެކަނބަލުންނަށް ދޭންޖެހޭ އުޖޫރައެއް ތިޔަބައިމީހުން އެކަނބަލުންނަށް ދެނީނަމަ، (އެކަމުގައި) ތިޔަބައިމީހުންގެ މައްޗަކަށް ކުށެއްނެތެވެ. އަދި، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި، ހަމަކަށަވަރުން، ﷲއީ، ތިޔަބައިމީހުން ކުރާ ކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެކަން ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₂ سورة البقرة","234","وَٱلَّذِينَ يُتَوَفَّوۡنَ مِنكُمۡ وَيَذَرُونَ أَزۡوَٰجٗا يَتَرَبَّصۡنَ بِأَنفُسِهِنَّ أَرۡبَعَةَ أَشۡهُرٖ وَعَشۡرٗاۖ فَإِذَا بَلَغۡنَ أَجَلَهُنَّ فَلَا جُنَاحَ عَلَيۡكُمۡ فِيمَا فَعَلۡنَ فِيٓ أَنفُسِهِنَّ بِٱلۡمَعۡرُوفِۗ وَٱللَّهُ بِمَا تَعۡمَلُونَ خَبِيرٞ ٢٣٤","والذين يتوفون منكم ويذرون أزواجا يتربصن بأنفسهن أربعة أشهر وعشرا فإذا بلغن أجلهن فلا جناح عليكم فيما فعلن في أنفسهن بالمعروف والله بما تعملون خبير","އަދި ތިޔަބައިމީހުންގެ ތެރެއިން މަރުވާ މީހުން ދޫކޮށްފައިދާ އަނބިން، އެކަނބަލުންގެ ނަފްސު ތަކާއިގެން ހަތަރުމަހާއި ދިހަދުވަހު (މީހުނާ ނީނދެ) އިންތިޒާރުކުރާހުށިކަމެވެ! ފަހެ، އެކަނބަލުންގެ އިއްދަގެ ދުވަސްތައް ފުރިހަމަކޮށްފިނަމަ، ޝަރުއީ ހަމައިގެމަތިން، އެކަނބަލުންގެ ނަފްސު ތަކާމެދު އެކަނބަލުން ކަންތައްކުރި ގޮތެއްގައި، ތިޔަބައިމީހުންގެ މައްޗަކަށް ކުށެއްނެތެވެ. ﷲއީ، ތިޔަބައިމީހުން ކުރާ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","235","وَلَا جُنَاحَ عَلَيۡكُمۡ فِيمَا عَرَّضۡتُم بِهِۦ مِنۡ خِطۡبَةِ ٱلنِّسَآءِ أَوۡ أَكۡنَنتُمۡ فِيٓ أَنفُسِكُمۡۚ عَلِمَ ٱللَّهُ أَنَّكُمۡ سَتَذۡكُرُونَهُنَّ وَلَٰكِن لَّا تُوَاعِدُوهُنَّ سِرًّا إِلَّآ أَن تَقُولُواْ قَوۡلٗا مَّعۡرُوفٗاۚ وَلَا تَعۡزِمُواْ عُقۡدَةَ ٱلنِّكَاحِ حَتَّىٰ يَبۡلُغَ ٱلۡكِتَٰبُ أَجَلَهُۥۚ وَٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ يَعۡلَمُ مَا فِيٓ أَنفُسِكُمۡ فَٱحۡذَرُوهُۚ وَٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ غَفُورٌ حَلِيمٞ ٢٣٥","ولا جناح عليكم فيما عرضتم به من خطبة النساء أو أكننتم في أنفسكم علم الله أنكم ستذكرونهن ولكن لا تواعدوهن سرا إلا أن تقولوا قولا معروفا ولا تعزموا عقدة النكاح حتى يبلغ الكتاب أجله واعلموا أن الله يعلم ما في أنفسكم فاحذروه واعلموا أن الله غفور حليم","އަދި، (ރަޖްއީ އިއްދަ ފިޔަވައި އެހެން އިއްދަ ގައިވާ) އަންހެނުންކުރެން، ތިޔަބައިމީހުން ކާވެނިކުރަން އެދޭކަމުގެ މައްޗަށް ދޭހަވާ ނުވަތަ އިޝާރަތްކުރާ ބަހެއް ބުނުމާމެދު، ނުވަތަ، ތިޔަބައިމީހުންގެ ހިތުތެރޭގައި (ކާވެނިކުރުމުގެ ގަސްދު) ފޮރުވާފައި ބޭއްވުމާމެދު، ތިޔަބައިމީހުންގެ މައްޗަކަށް ފާފައެއްނެތެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުން އެކަނބަލުން ކުރެން (ސަރީހަ ކޮށް) ކާވެނިކުރުމަށް އެދޭނޭކަން ﷲ ދެނެވޮޑިގެންވެއެވެ. އެހެނެއްކަމަކު، ޝަރުއީ ހަމައިގެ މަތިންވާ ބަހެއް ތިޔަބައިމީހުން ބުނުން ފިޔަވައި، އެކަނބަލުންނަށް ކާވެނިކުރުމާމެދު ވައުދުވެ ނުހަދާހުށިކަމެވެ! އަދި، އެކަނބަލުންގެ އިއްދަ ހަމަވެއްޖައުމަށްދާނދެން، ތިޔަބައިމީހުން (އެކަނބަލުންނާ) ކާވެނި އަގުދު ނުކުރާހުށިކަމެވެ! އަދި، ތިޔަބައިމީހުންގެ ނަފްސު ތަކުގައިވާ ކަންތައް ހަމަކަށަވަރުން، ﷲ ދެނެވޮޑިގެންވާކަން ތިޔަބައިމީހުން ދަންނާށެވެ! ވީމާ، ތިޔަބައިމީހުން، އެކަލާނގެއަށް ބިރުވެތިވެ ރައްކާތެރިވާށެވެ! އަދި، ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ހަލީމްވަންތަ، ރަސްކަލާނގެކަން ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₂ سورة البقرة","236","لَّا جُنَاحَ عَلَيۡكُمۡ إِن طَلَّقۡتُمُ ٱلنِّسَآءَ مَا لَمۡ تَمَسُّوهُنَّ أَوۡ تَفۡرِضُواْ لَهُنَّ فَرِيضَةٗۚ وَمَتِّعُوهُنَّ عَلَى ٱلۡمُوسِعِ قَدَرُهُۥ وَعَلَى ٱلۡمُقۡتِرِ قَدَرُهُۥ مَتَٰعَۢا بِٱلۡمَعۡرُوفِۖ حَقًّا عَلَى ٱلۡمُحۡسِنِينَ ٢٣٦","لا جناح عليكم إن طلقتم النساء ما لم تمسوهن أو تفرضوا لهن فريضة ومتعوهن على الموسع قدره وعلى المقتر قدره متاعا بالمعروف حقا على المحسنين","ތިޔަބައިމީހުން އަނބިންނާއެކު ރޭނުކުރާހާ ހިނދަކު، ނުވަތަ އެކަނބަލުންނަށް ރަނެއް ކަނޑައަޅާފައިނުވާހާ ހިނދަކު، ތިޔަބައިމީހުން، އެކަނބަލުން ވަރިކޮށްފިނަމަ، ތިޔަބައިމީހުންގެ މައްޗަކަށް ކުށެއްނެތެވެ. (ނަމަވެސް) ތިޔަބައިމީހުން، އެކަނބަލުންނަށް މުތުއާ ދޭށެވެ! (މުތުއާއަކީ ވަރިކުރެވޭ އަންހެންމީހާ ހިތްހަމަޖައްސައިލުމަށް ފިރިހެންމީހާގެ ފަރާތުންދެވޭ ބޭނުންތެރި ކޮންމެވެސް އެއްޗެކެވެ.) ތަނަވަސްކަން ލިބިގެންވާ މީހާގެ މައްޗަށް ވާޖިބު ވެގެންވަނީ، އޭނާގެ ވަރުން ދިނުމެވެ. އަތްމަތިދަތި މީހާގެ މައްޗަށްވެސް ވާޖިބު ވެގެންވަނީ، އޭނާގެ ވަރުން ދިނުމެވެ. ހެޔޮގޮތުގައި ދެވޭ މުތުއާއެއްގެ ގޮތުގައެވެ. (ވަރިކުރެވޭ މީހުންނަށް ދިނުން) އިހްސާން ތެރިންގެ މައްޗަށް ވާޖިބު ވެފައިވާ ހައްގެއްގެ ގޮތުގައެވެ.","",""],["₂ سورة البقرة","237","وَإِن طَلَّقۡتُمُوهُنَّ مِن قَبۡلِ أَن تَمَسُّوهُنَّ وَقَدۡ فَرَضۡتُمۡ لَهُنَّ فَرِيضَةٗ فَنِصۡفُ مَا فَرَضۡتُمۡ إِلَّآ أَن يَعۡفُونَ أَوۡ يَعۡفُوَاْ ٱلَّذِي بِيَدِهِۦ عُقۡدَةُ ٱلنِّكَاحِۚ وَأَن تَعۡفُوٓاْ أَقۡرَبُ لِلتَّقۡوَىٰۚ وَلَا تَنسَوُاْ ٱلۡفَضۡلَ بَيۡنَكُمۡۚ إِنَّ ٱللَّهَ بِمَا تَعۡمَلُونَ بَصِيرٌ ٢٣٧","وإن طلقتموهن من قبل أن تمسوهن وقد فرضتم لهن فريضة فنصف ما فرضتم إلا أن يعفون أو يعفو الذي بيده عقدة النكاح وأن تعفوا أقرب للتقوى ولا تنسوا الفضل بينكم إن الله بما تعملون بصير","އަދި، ތިޔަބައިމީހުން އެކަނބަލުންނަށް، ރަނެއް ކަނޑައަޅާފައިވާ ޙާލު، އެކަނބަލުންނާއެކު ރޭކުރުމުގެކުރިން، ތިޔަބައިމީހުން އެކަނބަލުން ވަރިކޮށްފިނަމަ، ފަހެ، ތިޔަބައިމީހުން ކަނޑައެޅި ރަނުގެ ދެބައިކުޅަ އެއްބައި، (އެކަނބަލުންނަށް) ދިނުންހުށްޓެވެ. (އެއީ) އެކަނބަލުން އަފޫކުރުމުން މެނުވީއެވެ. ނުވަތަ، ކާވެނީގެ ގޮށް އެމީހެއްގެ އަތުގައިވާ މީހާ އަފޫކުރުމުން މެނުވީއެވެ. ތަގުވާވެރިކަމާ އެންމެގާތްގޮތަކީ، ތިޔަބައިމީހުން އަފޫކުރުމެވެ. އަދި، ތިޔަބައިމީހުންގެ މެދުގައި، އެކަކު އަނެކެއްގެ މައްޗަށް އޮންނަންޖެހޭ އިހްސާން ތެރިވުން، ތިޔަބައިމީހުން ހަނދާންނައްތައި ނުލާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ތިޔަބައިމީހުން ކުރާ ކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","238","حَٰفِظُواْ عَلَى ٱلصَّلَوَٰتِ وَٱلصَّلَوٰةِ ٱلۡوُسۡطَىٰ وَقُومُواْ لِلَّهِ قَٰنِتِينَ ٢٣٨","حافظوا على الصلوات والصلاة الوسطى وقوموا لله قانتين","ތިޔަބައިމީހުން ނަމާދުތަކާއި، އަދި، މެދުނަމާދުގެ މައްޗަށް ރައްކާތެރިވާށެވެ! އަދި ތިޔަބައިމީހުން ﷲއަށް ކިޔަމަންތެރިވެ، މަޑުމައިތިރިކަމާއެކު (ނަމާދުގައި) ގާއިމުވެ ތިބޭށެވެ!","",""],["₂ سورة البقرة","239","فَإِنۡ خِفۡتُمۡ فَرِجَالًا أَوۡ رُكۡبَانٗاۖ فَإِذَآ أَمِنتُمۡ فَٱذۡكُرُواْ ٱللَّهَ كَمَا عَلَّمَكُم مَّا لَمۡ تَكُونُواْ تَعۡلَمُونَ ٢٣٩","فإن خفتم فرجالا أو ركبانا فإذا أمنتم فاذكروا الله كما علمكم ما لم تكونوا تعلمون","ފަހެ، ތިޔަބައިމީހުންނަށް ބިރުވެރިކަމެއް މެދުވެރިވެއްޖެނަމަ، ފައިމަގުގައި ހިނގަހިނގާތިބެގެން، ނުވަތަ، ސަވާރުވެތިބެގެން ނަމާދު ކުރާހުށިކަމެވެ! ދެން، ތިޔަބައިމީހުންނަށް އަމާން ކަން ލިބިއްޖެނަމަ، ފަހެ، ތިޔަބައިމީހުން، ﷲ ހަނދުމަކުރާށެވެ! (އެބަހީ: ކުރީގައި ނަމާދުކޮށް އުޅުނުގޮތަށް ނަމާދު ކުރާށެވެ!) ތިޔަބައި މީހުންނަށް އެނގިގެންނުވާ ކަންތައް، އެކަލާނގެ ތިޔަބައިމީހުންނަށް އުނގަންނައިދެއްވި ފަދައިންނެވެ.","",""],["₂ سورة البقرة","240","وَٱلَّذِينَ يُتَوَفَّوۡنَ مِنكُمۡ وَيَذَرُونَ أَزۡوَٰجٗا وَصِيَّةٗ لِّأَزۡوَٰجِهِم مَّتَٰعًا إِلَى ٱلۡحَوۡلِ غَيۡرَ إِخۡرَاجٖۚ فَإِنۡ خَرَجۡنَ فَلَا جُنَاحَ عَلَيۡكُمۡ فِي مَا فَعَلۡنَ فِيٓ أَنفُسِهِنَّ مِن مَّعۡرُوفٖۗ وَٱللَّهُ عَزِيزٌ حَكِيمٞ ٢٤٠","والذين يتوفون منكم ويذرون أزواجا وصية لأزواجهم متاعا إلى الحول غير إخراج فإن خرجن فلا جناح عليكم في ما فعلن في أنفسهن من معروف والله عزيز حكيم","ތިޔަބައިމީހުންގެ ތެރެއިން އަނބިން ދޫކޮށް މަރުވެދާ މީހުން، އެއުރެންގެ އަނބިން (ގެއިން) ނެރެލުމަކާނުލައި، އަހަރުދުވަހަށް ދާނދެން (ކެއިންބުއިމާއި ފޭރާމުގެގޮތުން) ބޭނުންކުރާނޭ އެއްޗެއް، އެއުރެންގެ އަނބިންނަށް ދިނުމަށް ވަސިއްޔަތްކުރާހުށިކަމެވެ! ފަހެ އެކަނބަލުން (ގެއިން) ނުކުމެއްޖެނަމަ، (ދަންނާށެވެ!) ޝަރުއީ ހަމައިގެމަތިން އެކަނބަލުންގެ ނަފްސު ތަކާމެދު އެކަނބަލުން ކުޅަކަމެއްގައި ފަހެ، ތިޔަބައިމީހުންގެ މައްޗަކަށް ކުށެއްނެތެވެ. ﷲއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ. (ނޯޓު: މި އާޔަތް ގައިވާ ވަސިއްޔަތާއި، ހުވަފަތްވެފައިވާ އަންހެނާ، ގެއިންނުނެރެ އަހަރުދުވަސްވަންދެން ބޭންދުމުގެ ހުކުމް ވަނީ ނަސްޚު ވެފައެވެ.)","",""],["₂ سورة البقرة","241","وَلِلۡمُطَلَّقَٰتِ مَتَٰعُۢ بِٱلۡمَعۡرُوفِۖ حَقًّا عَلَى ٱلۡمُتَّقِينَ ٢٤١","وللمطلقات متاع بالمعروف حقا على المتقين","ވަރިކޮށްފައިވާ އަންހެނުންނަށް އެކަށީގެންވާ ހެޔޮގޮތުގައި ނަފަގާތު ދިނުން ހުށްޓެވެ. ތަގުވާވެރިންގެ މައްޗަށްވާ ހައްގެއްގެ ގޮތުގައެވެ.","",""],["₂ سورة البقرة","242","كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمۡ ءَايَٰتِهِۦ لَعَلَّكُمۡ تَعۡقِلُونَ ٢٤٢","كذلك يبين الله لكم آياته لعلكم تعقلون","ﷲ، އެކަލާނގެ އާޔަތްތައް، ތިޔަބައިމީހުންނަށް އެފަދައިން ބަޔާންކޮށްދެއްވަނީ، ތިޔަބައިމީހުން ވިސްނުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","243","۞أَلَمۡ تَرَ إِلَى ٱلَّذِينَ خَرَجُواْ مِن دِيَٰرِهِمۡ وَهُمۡ أُلُوفٌ حَذَرَ ٱلۡمَوۡتِ فَقَالَ لَهُمُ ٱللَّهُ مُوتُواْ ثُمَّ أَحۡيَٰهُمۡۚ إِنَّ ٱللَّهَ لَذُو فَضۡلٍ عَلَى ٱلنَّاسِ وَلَٰكِنَّ أَكۡثَرَ ٱلنَّاسِ لَا يَشۡكُرُونَ ٢٤٣","ألم تر إلى الذين خرجوا من ديارهم وهم ألوف حذر الموت فقال لهم الله موتوا ثم أحياهم إن الله لذو فضل على الناس ولكن أكثر الناس لا يشكرون","އެތައްހާސް ބަޔަކުކަމުގައިވާ ޙާލު، މަރަށް ބިރުން އެއުރެންގެ ގޯތިގެދޮރުން ނުކުމެގެންދިޔަ މީހުންގެ ވާހަކަ، ކަލޭގެފާނަށް އެނގިވަޑައިގެންފައި ނުވޭތޯއެވެ؟ ފަހެ، ﷲ، އެއުރެންނަށް ވަހީކުރެއްވިއެވެ. ތިޔަބައިމީހުން މަރުވާށެވެ! (ދެން، އެއުރެން މަރުވީއެވެ.) ދެން، އެކަލާނގެ އެއުރެން ދިރުއްވިއެވެ. ހަމަކަށަވަރުން، ﷲއީ، މީސްތަކުންގެ މައްޗަށް ފަޟްލު ވަންތަވެރި ރަސްކަލާނގެކަން ކަށަވަރެވެ. އެހެނެއްކަމަކު، މީސްތަކުން ކުރެ ގިނަ މީހުން ޝުކުރެއް ނުކުރެތެވެ.","",""],["₂ سورة البقرة","244","وَقَٰتِلُواْ فِي سَبِيلِ ٱللَّهِ وَٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ سَمِيعٌ عَلِيمٞ ٢٤٤","وقاتلوا في سبيل الله واعلموا أن الله سميع عليم","އަދި، ތިޔަބައިމީހުން، ﷲގެ މަގުގައި ހަނގުރާމަކުރާށެވެ! އަދި، ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެކަން ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₂ سورة البقرة","245","مَّن ذَا ٱلَّذِي يُقۡرِضُ ٱللَّهَ قَرۡضًا حَسَنٗا فَيُضَٰعِفَهُۥ لَهُۥٓ أَضۡعَافٗا كَثِيرَةٗۚ وَٱللَّهُ يَقۡبِضُ وَيَبۡصُۜطُ وَإِلَيۡهِ تُرۡجَعُونَ ٢٤٥","من ذا الذي يقرض الله قرضا حسنا فيضاعفه له أضعافا كثيرة والله يقبض ويبسط وإليه ترجعون","ހެޔޮވެގެންވާ ދަރަންޏަކުން ﷲއަށް ދަރަނި ދޭހުށީ (އެބަހީ: ﷲއަށްޓަކައި ހޭދަކުރާހުށީ) ކާކުހެއްޔެވެ؟ ފަހެ، ގިނަވެގެންވާ ގުނަތަކަކަށް، ﷲ، އެ ދަރަނީގެ ހެޔޮ ޖަޒާ އެމީހަކަށް އިތުރުކޮށް ދެއްވާނެތެވެ. ރިޒްގު ދަތިކުރައްވަނީ، އަދި، ތަނަވަސްކުރައްވަނީވެސް ﷲއެވެ. އަދި، ތިޔަބައިމީހުން އެނބުރި ރުޖޫއަކުރައްވާހުށީ ހަމައެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["₂ سورة البقرة","246","أَلَمۡ تَرَ إِلَى ٱلۡمَلَإِ مِنۢ بَنِيٓ إِسۡرَـٰٓءِيلَ مِنۢ بَعۡدِ مُوسَىٰٓ إِذۡ قَالُواْ لِنَبِيّٖ لَّهُمُ ٱبۡعَثۡ لَنَا مَلِكٗا نُّقَٰتِلۡ فِي سَبِيلِ ٱللَّهِۖ قَالَ هَلۡ عَسَيۡتُمۡ إِن كُتِبَ عَلَيۡكُمُ ٱلۡقِتَالُ أَلَّا تُقَٰتِلُواْۖ قَالُواْ وَمَا لَنَآ أَلَّا نُقَٰتِلَ فِي سَبِيلِ ٱللَّهِ وَقَدۡ أُخۡرِجۡنَا مِن دِيَٰرِنَا وَأَبۡنَآئِنَاۖ فَلَمَّا كُتِبَ عَلَيۡهِمُ ٱلۡقِتَالُ تَوَلَّوۡاْ إِلَّا قَلِيلٗا مِّنۡهُمۡۚ وَٱللَّهُ عَلِيمُۢ بِٱلظَّـٰلِمِينَ ٢٤٦","ألم تر إلى الملإ من بني إسرائيل من بعد موسى إذ قالوا لنبي لهم ابعث لنا ملكا نقاتل في سبيل الله قال هل عسيتم إن كتب عليكم القتال ألا تقاتلوا قالوا وما لنا ألا نقاتل في سبيل الله وقد أخرجنا من ديارنا وأبنائنا فلما كتب عليهم القتال تولوا إلا قليلا منهم والله عليم بالظالمين","އިސްރާއީލުގެދަރިންގެ ތެރެއިން، މޫސާގެފާނަށްފަހުން އުޅުނު ޖަމާއަތެއްގެ މީހުންގެ ވާހަކަ، ކަލޭގެފާނަށް އެނގިވަޑައިގެންފައި ނުވޭތޯއެވެ؟ އެއީ، އެއުރެންގެ ނަބިއްޔަކަށް އެއުރެން ދެންނެވި ހިނދުގައެވެ. ﷲގެ މަގުގައި ތިމަންމެން ހަނގުރާމަކުރުމަށް ތިމަންމެންނަށް ރަސްކަލަކު ފޮނުއްވައި ދެއްވާށެވެ! އެ ނަބިއްޔާ ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންގެ މައްޗަށް ހަނގުރާމަ ފަރުޟުކުރެއްވިޔަސް، ތިޔަބައިމީހުން ހަނގުރާމަ ނުކޮށް ތިބެދާނެ ނޫންހެއްޔެވެ؟ އެއުރެން ދެންނެވޫއެވެ. ތިމަންމެންގެ ގޯތި ގެދޮރުންނާއި ދަރިންގެ ގާތުން ތިމަންމެން ނެރެލާފައިވާ ޙާލު، ﷲގެ މަގުގައި ތިމަންމެން ހަނގުރާމަ ނުކުރާންވީ ކީއްވެގެންތޯއެވެ؟ ދެން، އެއުރެންގެ މައްޗަށް ހަނގުރާމަ ފަރުޟުކުރެއްވިހިނދު، އެއުރެންގެ ތެރެއިން މަދުބަޔަކު މެނުވީ، އެކަމަށް ފުރަގަސްދިނޫއެވެ. ﷲއީ، އަނިޔާވެރިން މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","247","وَقَالَ لَهُمۡ نَبِيُّهُمۡ إِنَّ ٱللَّهَ قَدۡ بَعَثَ لَكُمۡ طَالُوتَ مَلِكٗاۚ قَالُوٓاْ أَنَّىٰ يَكُونُ لَهُ ٱلۡمُلۡكُ عَلَيۡنَا وَنَحۡنُ أَحَقُّ بِٱلۡمُلۡكِ مِنۡهُ وَلَمۡ يُؤۡتَ سَعَةٗ مِّنَ ٱلۡمَالِۚ قَالَ إِنَّ ٱللَّهَ ٱصۡطَفَىٰهُ عَلَيۡكُمۡ وَزَادَهُۥ بَسۡطَةٗ فِي ٱلۡعِلۡمِ وَٱلۡجِسۡمِۖ وَٱللَّهُ يُؤۡتِي مُلۡكَهُۥ مَن يَشَآءُۚ وَٱللَّهُ وَٰسِعٌ عَلِيمٞ ٢٤٧","وقال لهم نبيهم إن الله قد بعث لكم طالوت ملكا قالوا أنى يكون له الملك علينا ونحن أحق بالملك منه ولم يؤت سعة من المال قال إن الله اصطفاه عليكم وزاده بسطة في العلم والجسم والله يؤتي ملكه من يشاء والله واسع عليم","އަދި، އެއުރެންގެ ނަބިއްޔާ އެއުރެންނަށް ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ﷲ، ތިޔަބައިމީހުންނަށް ރަސްކަލެއްކަމުގައި ޠާލޫތު ފޮނުއްވައިފިއެވެ. އެއުރެން ދެންނެވޫއެވެ. އޭނާއަށްވުރެން ރަސްކަމަށް ތިމަންމެން ހައްގު ކަން ބޮޑުކަމުގައިވާއިރު، ތިމަންމެންގެ މައްޗަށް އޭނާއަށް ރަސްކަން އޮންނާނީ ކޮންފަދައަކުންތޯއެވެ؟ އަދި، އޭނާއަކަށް މުދަލުގެ ތަނަވަސްކަމެއްވެސް ލިބިފައެއް ނުވެއެވެ. އެ ނަބިއްޔާ ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ މައްޗަށް ﷲ، އޭނާ ޚިޔާރުކުރެއްވިއެވެ. އަދި، އޭނާއަށް އިލްމާއި، ހަށިގަނޑުގެ ގޮތުން ތަނަވަސްކަން އިތުރު ކުރެއްވިއެވެ. ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް، އެކަލާނގެ ވެރިކަން ދެއްވައެވެ. އަދި، ﷲއީ، ތަނަވަސްވަންތަ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","248","وَقَالَ لَهُمۡ نَبِيُّهُمۡ إِنَّ ءَايَةَ مُلۡكِهِۦٓ أَن يَأۡتِيَكُمُ ٱلتَّابُوتُ فِيهِ سَكِينَةٞ مِّن رَّبِّكُمۡ وَبَقِيَّةٞ مِّمَّا تَرَكَ ءَالُ مُوسَىٰ وَءَالُ هَٰرُونَ تَحۡمِلُهُ ٱلۡمَلَـٰٓئِكَةُۚ إِنَّ فِي ذَٰلِكَ لَأٓيَةٗ لَّكُمۡ إِن كُنتُم مُّؤۡمِنِينَ ٢٤٨","وقال لهم نبيهم إن آية ملكه أن يأتيكم التابوت فيه سكينة من ربكم وبقية مما ترك آل موسى وآل هارون تحمله الملائكة إن في ذلك لآية لكم إن كنتم مؤمنين","އަދި، އެއުރެންނަށް އެއުރެންގެ ނަބިއްޔާ ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، އޭނާގެ ވެރިކަމުގެ ހެތްކަކީ، ތިޔަބައިމީހުންނާ ހަމަޔަށް ތާބޫތު އައުމެވެ. ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ދެއްވާ ހިތްހަމަޖެހުމަކާއި، އަމާންކަމަކާއި، އަދި، މޫސާގެފާނުގެ އާލުވެރިންނާއި ހާރޫނުގެފާނުގެ އާލުވެރިން، ދޫކުރެއްވި ތަކެތީގެ ތެރެއިން ބައެއްތަކެތިވެސް، އެ ތާބޫތުގައި ވެއެވެ. (އެތަކެއްޗާއެކު) އެ ތާބޫތު، މަލާއިކަތުން އުފުއްލަވައިގެން ގެންނަވާނެތެވެ. ތިޔަބައިމީހުންނީ، މުއުމިނުން ކަމުގައިވާނަމަ، ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށް އެކަމުގައި ހެތްކެއްވާކަން ކަށަވަރެވެ. (ނޯޓު: ތާބޫތަކީ ފޮށްޓެކެވެ. އެ ފޮށީގައިވާ ތަކެއްޗާމެދު ތަފާތު ގޮތްގޮތަށް މުފައްސިރުން ލިޔުއްވާފައިވެއެވެ.)","",""],["₂ سورة البقرة","249","فَلَمَّا فَصَلَ طَالُوتُ بِٱلۡجُنُودِ قَالَ إِنَّ ٱللَّهَ مُبۡتَلِيكُم بِنَهَرٖ فَمَن شَرِبَ مِنۡهُ فَلَيۡسَ مِنِّي وَمَن لَّمۡ يَطۡعَمۡهُ فَإِنَّهُۥ مِنِّيٓ إِلَّا مَنِ ٱغۡتَرَفَ غُرۡفَةَۢ بِيَدِهِۦۚ فَشَرِبُواْ مِنۡهُ إِلَّا قَلِيلٗا مِّنۡهُمۡۚ فَلَمَّا جَاوَزَهُۥ هُوَ وَٱلَّذِينَ ءَامَنُواْ مَعَهُۥ قَالُواْ لَا طَاقَةَ لَنَا ٱلۡيَوۡمَ بِجَالُوتَ وَجُنُودِهِۦۚ قَالَ ٱلَّذِينَ يَظُنُّونَ أَنَّهُم مُّلَٰقُواْ ٱللَّهِ كَم مِّن فِئَةٖ قَلِيلَةٍ غَلَبَتۡ فِئَةٗ كَثِيرَةَۢ بِإِذۡنِ ٱللَّهِۗ وَٱللَّهُ مَعَ ٱلصَّـٰبِرِينَ ٢٤٩","فلما فصل طالوت بالجنود قال إن الله مبتليكم بنهر فمن شرب منه فليس مني ومن لم يطعمه فإنه مني إلا من اغترف غرفة بيده فشربوا منه إلا قليلا منهم فلما جاوزه هو والذين آمنوا معه قالوا لا طاقة لنا اليوم بجالوت وجنوده قال الذين يظنون أنهم ملاقو الله كم من فئة قليلة غلبت فئة كثيرة بإذن الله والله مع الصابرين","ދެން، ލަޝްކަރާއިގެން ޠާލޫތު ނުކުމެވަޑައިގަތްހިނދު އޭނާ ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ﷲ، ފެންކޯރަކުން ތިޔަބައިމީހުންގެ (ކިޔަމަންތެރިކަންހުރި) ގޮތް ބައްލަވާނެއެވެ. ފަހެ، އެ ކޯރުން ފެންބޮއިފި މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާ ތިމަންގެ މީހުންގެ ތެރެޔަކުން ނުވެތެވެ. އަދި، އޭގެ ރަހަ ލިބިނުގަތް މީހާއީ، ހަމަކަށަވަރުންވެސް، ތިމަންގެ މީހުންގެ ތެރެއިންވާ މީހެކެވެ. އެމީހެއްގެ އަތުން އަތްގޮށްޓެއްގެ ފެން ލިބިގަތްމީހާ މެނުވީއެވެ. ދެން، ފަހެ، އެއުރެންގެ ތެރެއިން މަދުބަޔަކު މެނުވީ، އެ ކޯރުން ފެންބޮއިފިއެވެ. ދެން އެއަށްފަހު، ޠާލޫތާއި، އޭނާގެ އަރިހުގައި އީމާން ވެގެންތިބި މީހުން، އެ ކޯރު ފަހަނަޅައި ހިނގައްޖެހިނދު، އެއުރެން (ގެ ތެރެއިން ބަޔަކު) ދެންނެވޫއެވެ. ޖަލޫތާއި، އޭނާގެ ލަޝްކަރާ ހަނގުރާމަ ކުރުމުގެ ކުޅަދާނަކަމެއް އަދަކު ތިމަންމެންނަކަށް ނެތެވެ. ހަމަކަށަވަރުން، ﷲއާ ބައްދަލުވާނޭކަން ޔަގީންކުރާމީހުން ބުނޫއެވެ. ﷲގެ އިޒުނަ ޔާއެކު ކިތައް ކިތައް މަދު ޖަމާއަތްގެ މީހުން، ގިނަ ޖަމާއަތްގެ މައްޗަށް ގަދަވެގެންފައިވޭ ހެއްޔެވެ؟ ﷲ ވޮޑިގެންވަނީ ކެތްތެރިންނާ އެކުގައެވެ.","",""],["₂ سورة البقرة","250","وَلَمَّا بَرَزُواْ لِجَالُوتَ وَجُنُودِهِۦ قَالُواْ رَبَّنَآ أَفۡرِغۡ عَلَيۡنَا صَبۡرٗا وَثَبِّتۡ أَقۡدَامَنَا وَٱنصُرۡنَا عَلَى ٱلۡقَوۡمِ ٱلۡكَٰفِرِينَ ٢٥٠","ولما برزوا لجالوت وجنوده قالوا ربنا أفرغ علينا صبرا وثبت أقدامنا وانصرنا على القوم الكافرين","އަދި، އެއުރެން (އެބަހީ: މުއުމިނުންގެ ލަޝްކަރު) ޖަލޫތާއި، އޭނާގެ ލަޝްކަރާ (ހަނގުރާމަ ކުރުމަށް ސަފުތައްހަދައި) ކުރިމަތިލީހިނދު، އެއުރެން ދެންނެވޫއެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެންނަށް ކެތްތެރިކަން ދެއްވާނދޭވެ! އަދި، އަޅަމެންގެ ފައިތިލަތައް ސާބިތުކޮށް ދެއްވާނދޭވެ! އަދި، ކާފިރު ވެގެންވާ ގައުމުގެ މައްޗަށް އަޅަމެންނަށް ނަސްރު ދެއްވާނދޭވެ!","",""],["₂ سورة البقرة","251","فَهَزَمُوهُم بِإِذۡنِ ٱللَّهِ وَقَتَلَ دَاوُۥدُ جَالُوتَ وَءَاتَىٰهُ ٱللَّهُ ٱلۡمُلۡكَ وَٱلۡحِكۡمَةَ وَعَلَّمَهُۥ مِمَّا يَشَآءُۗ وَلَوۡلَا دَفۡعُ ٱللَّهِ ٱلنَّاسَ بَعۡضَهُم بِبَعۡضٖ لَّفَسَدَتِ ٱلۡأَرۡضُ وَلَٰكِنَّ ٱللَّهَ ذُو فَضۡلٍ عَلَى ٱلۡعَٰلَمِينَ ٢٥١","فهزموهم بإذن الله وقتل داوود جالوت وآتاه الله الملك والحكمة وعلمه مما يشاء ولولا دفع الله الناس بعضهم ببعض لفسدت الأرض ولكن الله ذو فضل على العالمين","ފަހެ، އެއުރެން ﷲގެ އިޒުނަ ފުޅާއެކު ކާފިރުންގެ ލަޝްކަރު ބަލިކޮށްފޫއެވެ. އަދި، ދާވޫދުގެފާނު، ޖާލޫތު ގަތުލުކުރެއްވިއެވެ. އަދި، ﷲ، އެކަލޭގެފާނަށް ރަސްކަމާއި، ހިކުމަތް (އެބަހީ: ނަބީކަން) ދެއްވިއެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވާ ކަންތަކެއް އެކަލޭގެފާނަށް އެކަލާނގެ އުނގަންނައި ދެއްވިއެވެ. އަދި، މީސްތަކުންކުރެ އެއްބަޔަކު މެދުވެރި ކުރައްވައި އަނެއްބަޔަކު (ގެ ނުރައްކާތެރިކަން) ﷲ، ދުރުކުރެއްވުން ނުވާނަމަ، ބިން ފަސާދަވެއްޖައީސްކަން ކަށަވަރެވެ. އެހެނެއްކަމަކު ﷲއީ، އާލަމްތަކުގެ މައްޗަށް ފަޟްލު ވަންތަވެރި ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","252","تِلۡكَ ءَايَٰتُ ٱللَّهِ نَتۡلُوهَا عَلَيۡكَ بِٱلۡحَقِّۚ وَإِنَّكَ لَمِنَ ٱلۡمُرۡسَلِينَ ٢٥٢","تلك آيات الله نتلوها عليك بالحق وإنك لمن المرسلين","އެއީ، ﷲގެ އާޔަތް ތަކެވެ. ހައްގު ގޮތުގައި ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް އެ އާޔަތްތައް ކިޔައިދެއްވަމެވެ. އަދި، ހަމަކަށަވަރުން، ކަލޭގެފާނުވަނީ، ރަސޫލުންގެ ތެރެއިންކަން ކަށަވަރެވެ.","",""],["₂ سورة البقرة","253","۞تِلۡكَ ٱلرُّسُلُ فَضَّلۡنَا بَعۡضَهُمۡ عَلَىٰ بَعۡضٖۘ مِّنۡهُم مَّن كَلَّمَ ٱللَّهُۖ وَرَفَعَ بَعۡضَهُمۡ دَرَجَٰتٖۚ وَءَاتَيۡنَا عِيسَى ٱبۡنَ مَرۡيَمَ ٱلۡبَيِّنَٰتِ وَأَيَّدۡنَٰهُ بِرُوحِ ٱلۡقُدُسِۗ وَلَوۡ شَآءَ ٱللَّهُ مَا ٱقۡتَتَلَ ٱلَّذِينَ مِنۢ بَعۡدِهِم مِّنۢ بَعۡدِ مَا جَآءَتۡهُمُ ٱلۡبَيِّنَٰتُ وَلَٰكِنِ ٱخۡتَلَفُواْ فَمِنۡهُم مَّنۡ ءَامَنَ وَمِنۡهُم مَّن كَفَرَۚ وَلَوۡ شَآءَ ٱللَّهُ مَا ٱقۡتَتَلُواْ وَلَٰكِنَّ ٱللَّهَ يَفۡعَلُ مَا يُرِيدُ ٢٥٣","تلك الرسل فضلنا بعضهم على بعض منهم من كلم الله ورفع بعضهم درجات وآتينا عيسى ابن مريم البينات وأيدناه بروح القدس ولو شاء الله ما اقتتل الذين من بعدهم من بعد ما جاءتهم البينات ولكن اختلفوا فمنهم من آمن ومنهم من كفر ولو شاء الله ما اقتتلوا ولكن الله يفعل ما يريد","އެއީ ރަސޫލުންނެވެ. ތިމަންރަސްކަލާނގެ އެ ރަސޫލު ންކުރެ އެއްބަޔަކު އަނެއް ބަޔަކަށްވުރެ މާތްކުރެއްވީމެވެ. އެބޭކަލުންގެ ތެރެއިން ﷲ (ސީދާ) ބަސް ވަހީކުރެއްވި ބޭކަލުން ވެއެވެ. އަދި، އެކަލާނގެ، އެ ބޭކަލުންކުރެ ބަޔެއް ބޭކަލުން ދަރަޖައިގެ ގޮތުން މަތިވެރި ކުރެއްވިއެވެ. އަދި، މަރިޔަމްގެފާނުގެ ދަރިކަލުން ޢީސާގެފާނަށް، ބަޔާން ވެގެންވާ ހެކިތަކާއި، ހުއްޖަތްތައް، ތިމަންރަސްކަލާނގެ ދެއްވީމެވެ. އަދި، ރޫޙުލް ގުދުސްން (އެބަހީ: ޖިބްރީލުގެފާނު ފޮނުއްވުމުން) ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ބާރު ދެއްވީމެވެ. ﷲ އިރާދަކުރެއްވިނަމަ، އެބޭކަލުންގެ ފަހުން އައި މީހުން އެއުރެންނަށް ބަޔާންވެގެންވާ ހެކިތަކާއި، ހުއްޖަތްތައް އައުމަށްފަހު އެއުރެން އެކަކު އަނެކަކާ ހަނގުރާމަޔެއް ނުކުރީހެވެ. އެހެނެއްކަމަކު އެއުރެން ޚިލާފު ވެއްޖައޫއެވެ. ފަހެ، އެއުރެންގެ ތެރެއިން، އީމާންވި މީހުންނާއި، އަދި، ކާފިރުވި މީހުންވެސް ވެއެވެ. އަދި، ﷲ އިރާދަކުރެއްވިނަމަ، އެއުރެން އެކަކު އަނެކަކާ ހަނގުރާމަޔެއް ނުކުރީހެވެ. އެހެނެއްކަމަކު ﷲ އެކަލާނގެ އިރާދަކުރައްވާ ކަމެއް ކުރައްވައެވެ.","",""],["₂ سورة البقرة","254","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ أَنفِقُواْ مِمَّا رَزَقۡنَٰكُم مِّن قَبۡلِ أَن يَأۡتِيَ يَوۡمٞ لَّا بَيۡعٞ فِيهِ وَلَا خُلَّةٞ وَلَا شَفَٰعَةٞۗ وَٱلۡكَٰفِرُونَ هُمُ ٱلظَّـٰلِمُونَ ٢٥٤","يا أيها الذين آمنوا أنفقوا مما رزقناكم من قبل أن يأتي يوم لا بيع فيه ولا خلة ولا شفاعة والكافرون هم الظالمون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ ދެއްވި ތަކެތިން ތިޔަބައިމީހުން ހޭދަކުރާށެވެ! (އެއީ) ދުވަހެއް އައުމުގެ ކުރިންނެވެ. އެ ދުވަހުގައި ވިޔަފާރި ކުރުމެއް (އެބަހީ: ފިދުޔަ ދީގެން ސަލާމަތްވާނެ މަގެއް) ނުވެއެވެ. އަދި، (މަންފާޔެއް ކޮށްދެނިވި) ރަހުމަތް ތެރިކަމެއްވެސް ނުވެއެވެ. އަދި، (އެކަލާނގެ އިޒުނަފުޅުން މެނުވީ) ޝަފާއަތް ތެރިކަމެއްވެސް ނުމެވޭމެއެވެ. ކާފިރުންނަކީ ހަމަ އަނިޔާވެރިންނެވެ.","",""],["₂ سورة البقرة","255","ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَ ٱلۡحَيُّ ٱلۡقَيُّومُۚ لَا تَأۡخُذُهُۥ سِنَةٞ وَلَا نَوۡمٞۚ لَّهُۥ مَا فِي ٱلسَّمَٰوَٰتِ وَمَا فِي ٱلۡأَرۡضِۗ مَن ذَا ٱلَّذِي يَشۡفَعُ عِندَهُۥٓ إِلَّا بِإِذۡنِهِۦۚ يَعۡلَمُ مَا بَيۡنَ أَيۡدِيهِمۡ وَمَا خَلۡفَهُمۡۖ وَلَا يُحِيطُونَ بِشَيۡءٖ مِّنۡ عِلۡمِهِۦٓ إِلَّا بِمَا شَآءَۚ وَسِعَ كُرۡسِيُّهُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضَۖ وَلَا يَـُٔودُهُۥ حِفۡظُهُمَاۚ وَهُوَ ٱلۡعَلِيُّ ٱلۡعَظِيمُ ٢٥٥","الله لا إله إلا هو الحي القيوم لا تأخذه سنة ولا نوم له ما في السماوات وما في الأرض من ذا الذي يشفع عنده إلا بإذنه يعلم ما بين أيديهم وما خلفهم ولا يحيطون بشيء من علمه إلا بما شاء وسع كرسيه السماوات والأرض ولا يئوده حفظهما وهو العلي العظيم","ﷲއީ، އެކަލާނގެ ފިޔަވައި ހައްގު ވެގެން އަޅުކަމެއް ވެވޭ އިލާހަކުނުވާ ރަސްކަލާނގެއެވެ. ދިރިދެމިވޮޑިގެންވާ، ދާއިމަށް ގާއިމުވެ ވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އަވަހާރަފުޅު އައުމެއް އަދި، އަވަހާރަފުޅު ލެއްޕެވުމެއްވެސް އެކަލާނގެއަކަށް ނުވެއެވެ. އުޑުތަކުގައި ވާހައި އެއްޗަކާއި، އަދި، ބިމުގައި ވާހައި އެއްޗެއް މިލްކުވެގެންވަނީ އެކަލާނގެއަށެވެ. އެކަލާނގެ އިޒުނަ ފުޅާ ނުލައި އެކަލާނގެ ހަޒުރަތުގައި ޝަފާއަތް ތެރިވާނޭ މީހަކީ ކާކުހެއްޔެވެ؟ އެއުރެންގެ ކުރިން (އެބަހީ: ޚަލްގު ތަކުންގެ ކުރިން) އިސްވެގޮސްފައިވާހައި ކަމަކާއި، އެއުރެންގެ ފަހުން ވާނޭހައި ކަމެއްވެސް އެކަލާނގެ ދެނެވޮޑިގެންވެއެވެ. އަދި، އެކަލާނގެ އިލްމު ފުޅުގެ ތެރެއިން އެކަލާނގެ އިރާދަކުރެއްވިކަމެއް ފިޔަވައި، އެއްވެސް އެއްޗެއް އެއުރެންނަކަށް އެނގިގެނެއް ނުވެއެވެ. އެކަލާނގެ ކުރުސިއްޔު، އުޑުތަކާއި، ބިމުގެ އެންމެހައި ކަންކޮޅުތަކަށް ތަނަވަސް ވެގެންވެއެވެ. އެ އުޑުތަކާއި، ބިން، ރައްކާތެރި ކުރައްވައި ހިފެހެއްޓެވުމަށް އެކަލާނގެ ހަޒުރަތަކަށް ކުޑަވެސް ބުރަކަމެއް ނުވެއެވެ. އަދި، އެކަލާނގެއީ، އެންމެ މަތިވެރި އެންމެ މާތް ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","256","لَآ إِكۡرَاهَ فِي ٱلدِّينِۖ قَد تَّبَيَّنَ ٱلرُّشۡدُ مِنَ ٱلۡغَيِّۚ فَمَن يَكۡفُرۡ بِٱلطَّـٰغُوتِ وَيُؤۡمِنۢ بِٱللَّهِ فَقَدِ ٱسۡتَمۡسَكَ بِٱلۡعُرۡوَةِ ٱلۡوُثۡقَىٰ لَا ٱنفِصَامَ لَهَاۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ ٢٥٦","لا إكراه في الدين قد تبين الرشد من الغي فمن يكفر بالطاغوت ويؤمن بالله فقد استمسك بالعروة الوثقى لا انفصام لها والله سميع عليم","ދީނަށް ވެއްދުމުގައި މަޖުބޫރުކުރުމެއް ނެތެވެ. ހަމަކަށަވަރުން، މަގުފުރެދުމުގެ އަނދިރިކަމުގެ ތެރެއިން، ހިދާޔަތްގެ ސާފު އަލިމަގު އެނގި ފާޅުވެއްޖެއެވެ. ފަހެ، ޝައިތާނު އާޔަށް ކާފިރުވެ ﷲއަށް އީމާން ވާމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާ، އެންމެ ވަރުގަދަ އަގީދާގައި ހިފަހައްޓައިފިކަން ކަށަވަރެވެ. ނެތި ދިޔުމެއް އެޔަކަށް ނުވެއެވެ. ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","257","ٱللَّهُ وَلِيُّ ٱلَّذِينَ ءَامَنُواْ يُخۡرِجُهُم مِّنَ ٱلظُّلُمَٰتِ إِلَى ٱلنُّورِۖ وَٱلَّذِينَ كَفَرُوٓاْ أَوۡلِيَآؤُهُمُ ٱلطَّـٰغُوتُ يُخۡرِجُونَهُم مِّنَ ٱلنُّورِ إِلَى ٱلظُّلُمَٰتِۗ أُوْلَـٰٓئِكَ أَصۡحَٰبُ ٱلنَّارِۖ هُمۡ فِيهَا خَٰلِدُونَ ٢٥٧","الله ولي الذين آمنوا يخرجهم من الظلمات إلى النور والذين كفروا أولياؤهم الطاغوت يخرجونهم من النور إلى الظلمات أولئك أصحاب النار هم فيها خالدون","ﷲއީ، އީމާންވި މީހުންނަށް އެހީތެރިވެ، ވާގިވެރިވެ ވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އެކަލާނގެ، އަނދިރިކަމުގެ ތެރެއިން އަލިކަމަށް އެއުރެން ނެރުއްވައެވެ. އަދި، ކާފިރުވި މީހުންގެ އެކުވެރި ވާގިވެރިންނަކީ، ޝައިތާނުންނެވެ. އަލިކަމުގެ ތެރެއިން އަނދިރިކަމަށް، އެ ޝައިތާނުން އެއުރެން ނެރެތެވެ. އެއުރެންނީ، ނަރަކައިގެ އަހުލުވެރިންނެވެ. އެއުރެން އެތާނގައި ދެމިތިބޭނެތެވެ.","",""],["₂ سورة البقرة","258","أَلَمۡ تَرَ إِلَى ٱلَّذِي حَآجَّ إِبۡرَٰهِـۧمَ فِي رَبِّهِۦٓ أَنۡ ءَاتَىٰهُ ٱللَّهُ ٱلۡمُلۡكَ إِذۡ قَالَ إِبۡرَٰهِـۧمُ رَبِّيَ ٱلَّذِي يُحۡيِۦ وَيُمِيتُ قَالَ أَنَا۠ أُحۡيِۦ وَأُمِيتُۖ قَالَ إِبۡرَٰهِـۧمُ فَإِنَّ ٱللَّهَ يَأۡتِي بِٱلشَّمۡسِ مِنَ ٱلۡمَشۡرِقِ فَأۡتِ بِهَا مِنَ ٱلۡمَغۡرِبِ فَبُهِتَ ٱلَّذِي كَفَرَۗ وَٱللَّهُ لَا يَهۡدِي ٱلۡقَوۡمَ ٱلظَّـٰلِمِينَ ٢٥٨","ألم تر إلى الذي حاج إبراهيم في ربه أن آتاه الله الملك إذ قال إبراهيم ربي الذي يحيي ويميت قال أنا أحيي وأميت قال إبراهيم فإن الله يأتي بالشمس من المشرق فأت بها من المغرب فبهت الذي كفر والله لا يهدي القوم الظالمين","ﷲ، އޭނާއަށް ރަސްކަންދެއްވާފައިވާތީ، އިބްރާހީމްގެފާނުގެ ވެރިރަސްކަލާނގެއާމެދު އެކަލޭގެފާނާ ޖަދަލުކުޅަ މީހާޔަށް ކަލޭގެފާނު ވިސްނައި ފިކުރު ނުކުރައްވަމުތޯއެވެ؟ (އެއީ) އިބްރާހީމްގެފާނު ވިދާޅުވިހިނދެވެ. ދިރުއްވައި މަރުގަންނަވަނީ ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއެވެ. އޭނާ ދެންނެވިއެވެ. އަހަރެންވެސް ދިރުވައި އަދި މަރަމެވެ. އިބްރާހީމްގެފާނު ވިދާޅުވިއެވެ. ފަހެ، ހަމަކަށަވަރުން، ﷲ، އިރުމަތީފަރާތުން އިރު ގެންނަވައެވެ. ފަހެ، ކަލޭ، އެ އިރު ހުޅަނގުފަރާތުން ނިކަން ގެނެސް ބަލާށެވެ! ދެން، އެ ކާފިރުވި ކަލޭގެ ހައިރާންވެ ބަސްހުއްޓިއްޖެއެވެ. އަނިޔާވެރިވެގެންވާ ގައުމަކަށް ﷲ ތެދުމަގެއް ނުދައްކަވައެވެ.","",""],["₂ سورة البقرة","259","أَوۡ كَٱلَّذِي مَرَّ عَلَىٰ قَرۡيَةٖ وَهِيَ خَاوِيَةٌ عَلَىٰ عُرُوشِهَا قَالَ أَنَّىٰ يُحۡيِۦ هَٰذِهِ ٱللَّهُ بَعۡدَ مَوۡتِهَاۖ فَأَمَاتَهُ ٱللَّهُ مِاْئَةَ عَامٖ ثُمَّ بَعَثَهُۥۖ قَالَ كَمۡ لَبِثۡتَۖ قَالَ لَبِثۡتُ يَوۡمًا أَوۡ بَعۡضَ يَوۡمٖۖ قَالَ بَل لَّبِثۡتَ مِاْئَةَ عَامٖ فَٱنظُرۡ إِلَىٰ طَعَامِكَ وَشَرَابِكَ لَمۡ يَتَسَنَّهۡۖ وَٱنظُرۡ إِلَىٰ حِمَارِكَ وَلِنَجۡعَلَكَ ءَايَةٗ لِّلنَّاسِۖ وَٱنظُرۡ إِلَى ٱلۡعِظَامِ كَيۡفَ نُنشِزُهَا ثُمَّ نَكۡسُوهَا لَحۡمٗاۚ فَلَمَّا تَبَيَّنَ لَهُۥ قَالَ أَعۡلَمُ أَنَّ ٱللَّهَ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٞ ٢٥٩","أو كالذي مر على قرية وهي خاوية على عروشها قال أنى يحيي هذه الله بعد موتها فأماته الله مائة عام ثم بعثه قال كم لبثت قال لبثت يوما أو بعض يوم قال بل لبثت مائة عام فانظر إلى طعامك وشرابك لم يتسنه وانظر إلى حمارك ولنجعلك آية للناس وانظر إلى العظام كيف ننشزها ثم نكسوها لحما فلما تبين له قال أعلم أن الله على كل شيء قدير","ނުވަތަ، ހިޔާވަހިކަންދޭ ފުރާޅުތަކާއި އިމާރާތްތައް ވެއްޓި ފަޅުވެފައިވާ ރަށެއްގެ ކައިރިންލާފައި ވަޑައިގަތް ބޭކަލެއްގެ ވާހަކަޔާމެދު ކަލޭގެފާނު ވިސްނައި ފިކުރު ނުކުރައްވަމުތޯއެވެ؟ އޭނާ ވިދާޅުވިއެވެ. މިރަށް މަރުވުމަށްފަހު، (އެބަހީ: ފަޅުވެ ވީރާނާ ވުމަށްފަހު) ﷲ، އަލުން އެރަށް ދިރުއްވާނީ ކޮންފަދައަކުން ހެއްޔެވެ؟ ދެން، ﷲ، ސަތޭކަ އަހަރަށް، އޭނާ މަރުގެންނެވިއެވެ. ދެން އަލުން އޭނާ ދިރުއްވައި ހަޔާތަށް ފޮނުއްވިއެވެ. އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ކަލޭގެފާނު އަވަހާރަވެފައި އޮންނެވީ ކިތައްދުވަހުތޯއެވެ؟ އޭނާ ދެންނެވިއެވެ. ތިމަންއަޅާ އޮތީ އެންމެ ދުވަހަކުއެވެ. ނުވަތަ ދުވަހަކުން ބަޔެއްގައެވެ. އެކަލާނގެ ވަހީކުރެއްވިއެވެ. އަދި ކިޔެއްހެއްޔެވެ! ސަތޭކަ އަހަރު ވާނދެން ކަލޭގެފާނު އޮންނެވީމުއެވެ. ފަހެ، ކަލޭގެފާނުގެ ކާތަކެއްޗަށާއި ބޯތަކެއްޗަށް ބައްލަވާށެވެ! އެތަކެއްޗަށް ބަދަލެއްނާދެއެވެ. އަދި، ކަލޭގެފާނުގެ ހިމާރަށް ބައްލަވާށެވެ! (އެކަން އެގޮތަށް ކުރެއްވީ ކަލޭގެފާނު ދެނެވަޑައިގަތުމަށްޓަކައެވެ.) އަދި، މީސްތަކުންނަށް ހެތްކެއްކަމުގައި ކަލޭގެފާނު ލެއްވުމަށްޓަކައެވެ. އަދި، ތިމަންރަސްކަލާނގެ އެ ކަށިތައް އެއްކުރައްވައި، ދެން، އެ ކަށިތަކުގައި މަސް ލައްވަނީ ކޮންފަދައަކުންކަން ކަލޭގެފާނު ދެކެވަޑައިގެން ބައްލަވާށެވެ! ދެން، އޭނާއަށް އެކަން ބަޔާންވެ އެނގިވަޑައިގަތްހިނދު ދެންނެވިއެވެ. ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެ ކަމަކަށްމެ ކުޅަދުންވަންތަ ކަލާނގެކަން ޔަގީން ކޮށް ދެނެގަންނަމެވެ.","",""],["₂ سورة البقرة","260","وَإِذۡ قَالَ إِبۡرَٰهِـۧمُ رَبِّ أَرِنِي كَيۡفَ تُحۡيِ ٱلۡمَوۡتَىٰۖ قَالَ أَوَ لَمۡ تُؤۡمِنۖ قَالَ بَلَىٰ وَلَٰكِن لِّيَطۡمَئِنَّ قَلۡبِيۖ قَالَ فَخُذۡ أَرۡبَعَةٗ مِّنَ ٱلطَّيۡرِ فَصُرۡهُنَّ إِلَيۡكَ ثُمَّ ٱجۡعَلۡ عَلَىٰ كُلِّ جَبَلٖ مِّنۡهُنَّ جُزۡءٗا ثُمَّ ٱدۡعُهُنَّ يَأۡتِينَكَ سَعۡيٗاۚ وَٱعۡلَمۡ أَنَّ ٱللَّهَ عَزِيزٌ حَكِيمٞ ٢٦٠","وإذ قال إبراهيم رب أرني كيف تحيي الموتى قال أولم تؤمن قال بلى ولكن ليطمئن قلبي قال فخذ أربعة من الطير فصرهن إليك ثم اجعل على كل جبل منهن جزءا ثم ادعهن يأتينك سعيا واعلم أن الله عزيز حكيم","އަދި، އިބްރާހީމްގެފާނު ދެންނެވިހިނދު ހަނދުމަކުރާށެވެ! އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! އިބަރަސްކަލާނގެ، މަރުވެފައިވާ ތަކެތި ދިރުއްވަނީ ކޮންފަދައަކުންކަން އިބަރަސްކަލާނގެ މިއަޅާއަށް ދައްކަވައިފާނދޭވެ! އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ފަހެ، ކަލޭގެފާނު އީމާން ވެވަޑައި ނުގަންނަވަނީތޯއެވެ؟ އެކަލޭގެފާނު ދެންނެވިއެވެ. ނޫނެކެވެ! (މިއަޅާވަނީ އީމާން ވެގެންނެވެ.) އެހެނެއްކަމަކު، މިއަޅާގެ ހިތްހަމަޖެހި އިޠުމިއުނާން ކަން ލިބުމަށްޓަކައެވެ. އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ފަހެ، ކަލޭގެފާނު، ހަތަރު ދޫންޏެއް، ހިއްޕަވާށެވެ! ދެން އެ އެއްޗެތި ކަލޭގެފާނުގެ ބާރުގެ ދަށަށް ގެންނަވައި، ކަތިލައްވައި، ކޮށްޓަވައި، މޮޑުއްވައި، އެކަތި އަނެކައްޗާ އެއްކުރައްވައި ހައްދަވާށެވެ! ދެން (ބައިކުރައްވައި) އެއިން ބައެއް ކޮންމެ ފަރުބަދަޔެއްގެ މައްޗަށް ލައްވާށެވެ! ދެން، އެ އެއްޗިއްސަށް ކަލޭގެފާނު ގޮވައިލައްވާށެވެ! އެހިނދު، އެ އެއްޗެތި ކަލޭގެފާނުގެ އަރިހަށް އަވަސް އަވަހަށް އަންނަ ހުށްޓެވެ. ހަމަކަށަވަރުން، ﷲއީ، ޢަޒީޒުވަންތަ ޙަކީމްވަންތަ ރަސްކަލާނގެކަން ދަންނާށެވެ!","",""],["₂ سورة البقرة","261","مَّثَلُ ٱلَّذِينَ يُنفِقُونَ أَمۡوَٰلَهُمۡ فِي سَبِيلِ ٱللَّهِ كَمَثَلِ حَبَّةٍ أَنۢبَتَتۡ سَبۡعَ سَنَابِلَ فِي كُلِّ سُنۢبُلَةٖ مِّاْئَةُ حَبَّةٖۗ وَٱللَّهُ يُضَٰعِفُ لِمَن يَشَآءُۚ وَٱللَّهُ وَٰسِعٌ عَلِيمٌ ٢٦١","مثل الذين ينفقون أموالهم في سبيل الله كمثل حبة أنبتت سبع سنابل في كل سنبلة مائة حبة والله يضاعف لمن يشاء والله واسع عليم","ﷲގެ މަގުގައި، އެއުރެންގެ މުދާ ހޭދަކުރާ މީހުން ހޭދަކުރާ ތަކެތީގެ މިސާލީ، ކޮންމެ ކުރާގަނޑެއްގައި ސަތޭކަ އޮށް ހުންނަ ހަތް ކުރާގަނޑު އުފައްދާ އޮށެއްގެ މިސާލެވެ. ﷲ އިރާދަކުރައްވާ މީހަކަށް (ސަވާބު) ގިނަގުނަ ކުރައްވައެވެ. އަދި، ﷲއީ، ތަނަވަސްވަންތަ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","262","ٱلَّذِينَ يُنفِقُونَ أَمۡوَٰلَهُمۡ فِي سَبِيلِ ٱللَّهِ ثُمَّ لَا يُتۡبِعُونَ مَآ أَنفَقُواْ مَنّٗا وَلَآ أَذٗى لَّهُمۡ أَجۡرُهُمۡ عِندَ رَبِّهِمۡ وَلَا خَوۡفٌ عَلَيۡهِمۡ وَلَا هُمۡ يَحۡزَنُونَ ٢٦٢","الذين ينفقون أموالهم في سبيل الله ثم لا يتبعون ما أنفقوا منا ولا أذى لهم أجرهم عند ربهم ولا خوف عليهم ولا هم يحزنون","އެއުރެންގެ މުދާ، ﷲގެ މަގުގައި ހޭދަކޮށް، ދެން އެއަށްފަހު، އެއުރެން ހޭދަކުރި އެއްޗަކާ ގުޅިގެން ކަލަގޮވުމެއްނުވާ، އަދި (ބަހުން ނުވަތަ ޢަމަލުން ވިޔަސް) އުނދަގުލެއް ނުދޭ މީހުންނަށް އެއުރެންގެ އުޖޫރަ (އެބަހީ: ސަވާބު) އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި އެއުރެންނަށް ވެއެވެ. އަދި، އެއުރެންގެ މައްޗަކަށް އެއްވެސް ބިރެއް ނެތެވެ. އަދި އެއުރެންނީ ހިތާމަކުރާނޭ ބަޔަކު ކަމުގައިވެސް ނުމެވޭމެއެވެ.","",""],["₂ سورة البقرة","263","۞قَوۡلٞ مَّعۡرُوفٞ وَمَغۡفِرَةٌ خَيۡرٞ مِّن صَدَقَةٖ يَتۡبَعُهَآ أَذٗىۗ وَٱللَّهُ غَنِيٌّ حَلِيمٞ ٢٦٣","قول معروف ومغفرة خير من صدقة يتبعها أذى والله غني حليم","އެ ސަދަގާތަކާ ގުޅިގެން އުނދަގުލެއްދޭ ސަދަގާތަކަށްވުރެ ރަނގަޅު ހެޔޮބަހެއް ބުނުން، އަދި އަފޫކުރުން، ހެޔޮކަން މާބޮޑެވެ. ﷲއީ، ފުދިވޮޑިގެންވާ، ހަލީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","264","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تُبۡطِلُواْ صَدَقَٰتِكُم بِٱلۡمَنِّ وَٱلۡأَذَىٰ كَٱلَّذِي يُنفِقُ مَالَهُۥ رِئَآءَ ٱلنَّاسِ وَلَا يُؤۡمِنُ بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِۖ فَمَثَلُهُۥ كَمَثَلِ صَفۡوَانٍ عَلَيۡهِ تُرَابٞ فَأَصَابَهُۥ وَابِلٞ فَتَرَكَهُۥ صَلۡدٗاۖ لَّا يَقۡدِرُونَ عَلَىٰ شَيۡءٖ مِّمَّا كَسَبُواْۗ وَٱللَّهُ لَا يَهۡدِي ٱلۡقَوۡمَ ٱلۡكَٰفِرِينَ ٢٦٤","يا أيها الذين آمنوا لا تبطلوا صدقاتكم بالمن والأذى كالذي ينفق ماله رئاء الناس ولا يؤمن بالله واليوم الآخر فمثله كمثل صفوان عليه تراب فأصابه وابل فتركه صلدا لا يقدرون على شيء مما كسبوا والله لا يهدي القوم الكافرين","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ކަލަގޮވުމުންނާއި، އުނދަގޫ ދިނުމުން ތިޔަބައިމީހުންގެ ސަދަގާތްތައް ބާތިލު ނުކުރާ ހުށިކަމެވެ! މީހުންނަށް ދެއްކުމަށްޓަކައި އެމީހެއްގެ މުދާ ހޭދަކުރާ މީހެއްގެ މިސާލު ފަދައިންނެވެ. ﷲއަށާއި އާޚިރަތް ދުވަހަށް އޭނާ އީމާނެއް ނުވެތެވެ. ފަހެ، އޭނާގެ މިސާލީ، އެ ހިލަޔެއްގެ މަތީގައި ވެލިތަކެއް ހުށްޓައި އެ ހިލައިގެ މައްޗަށް ބޯވާރޭގަނޑެއް ވެހި، އޭގެ މަތީގައި އެއްވެސް އެއްޗެއް ނެތިގޮސްފައިވާ އޮމާން، ހިލަޔެއްގެ މިސާލެވެ. އެއުރެން ކުޅަ މަސައްކަތުގެ ތެރެއިން އެއްވެސް އެއްޗެއްގެ މައްޗަށް އެއުރެންނަކަށް ކުޅަދާނަކަމެއް ލިބިގެނެއް ނުވެތެވެ. (އެބަހީ: އެއުރެން ކުޅަ ޢަމަލަށް އާޚިރަތް ދުވަހުން އެއުރެންނަކަށް އެއްވެސް ސަވާބެއް ނުލިބޭ ހުށްޓެވެ.) ކާފިރު ވެގެންވާ ގައުމަކަށް ﷲ ތެދުމަގެއް ނުދައްކަވައެވެ.","",""],["₂ سورة البقرة","265","وَمَثَلُ ٱلَّذِينَ يُنفِقُونَ أَمۡوَٰلَهُمُ ٱبۡتِغَآءَ مَرۡضَاتِ ٱللَّهِ وَتَثۡبِيتٗا مِّنۡ أَنفُسِهِمۡ كَمَثَلِ جَنَّةِۭ بِرَبۡوَةٍ أَصَابَهَا وَابِلٞ فَـَٔاتَتۡ أُكُلَهَا ضِعۡفَيۡنِ فَإِن لَّمۡ يُصِبۡهَا وَابِلٞ فَطَلّٞۗ وَٱللَّهُ بِمَا تَعۡمَلُونَ بَصِيرٌ ٢٦٥","ومثل الذين ينفقون أموالهم ابتغاء مرضات الله وتثبيتا من أنفسهم كمثل جنة بربوة أصابها وابل فآتت أكلها ضعفين فإن لم يصبها وابل فطل والله بما تعملون بصير","އަދި، ﷲގެ ރުއްސެވުންއެދި، އަދި، (ﷲގެ ސަވާބާއި ދަރުމަ ލިބޭނެކަމަށް) އެއުރެންގެ ނަފްސު ތަކުން ޔަގީން ކޮށް ކަށަވަރު ކޮށްގެންތިބެ، އެއުރެންގެ މުދާ ހޭދަކުރާ މީހުން ހޭދަކުރާ ތަކެތީގެ މިސާލީ، އުސްބިމެއްގައިވާ ބަގީޗާއަކަށް ބޯވާރޭއެއް ވެހި، އެތާނގެ މޭވާ، ދެގުނައަށް އިތުރުވެގެންދާ، އަދި، ބޯވާރެއެއް ނުވެހުނުނަމަ، ހިމަފޮދު ވާރެއެއް ވެހޭ ބަގީޗާއެއްގެ މިސާލެވެ. (މިއިން ކޮންމެ ގޮތެއްގައިވެސް މޭވާ ލިބި އިތުރުވެއެވެ.) ﷲއީ، ތިޔަބައިމީހުން ކުރާ ކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","266","أَيَوَدُّ أَحَدُكُمۡ أَن تَكُونَ لَهُۥ جَنَّةٞ مِّن نَّخِيلٖ وَأَعۡنَابٖ تَجۡرِي مِن تَحۡتِهَا ٱلۡأَنۡهَٰرُ لَهُۥ فِيهَا مِن كُلِّ ٱلثَّمَرَٰتِ وَأَصَابَهُ ٱلۡكِبَرُ وَلَهُۥ ذُرِّيَّةٞ ضُعَفَآءُ فَأَصَابَهَآ إِعۡصَارٞ فِيهِ نَارٞ فَٱحۡتَرَقَتۡۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمُ ٱلۡأٓيَٰتِ لَعَلَّكُمۡ تَتَفَكَّرُونَ ٢٦٦","أيود أحدكم أن تكون له جنة من نخيل وأعناب تجري من تحتها الأنهار له فيها من كل الثمرات وأصابه الكبر وله ذرية ضعفاء فأصابها إعصار فيه نار فاحترقت كذلك يبين الله لكم الآيات لعلكم تتفكرون","ކަދުރު ރުކާއި، މޭބިސްކަދުރު ހުރި ބަގީޗާއެއް އެ މީހަކަށް ލިބި، އެ ބަގީޗާގެ ދަށުން ކޯރުތައް ހިނގަހިނގާހުރެ، އެތަނުން އޭނާއަށް ހުރިހާ ބާވަތެއްގެ މޭވާ ލިބި، ދެން އޭނާއަށް ނިކަމެތި ޅަދަރިންތަކެއްވާ ޙާލުގައި، (މަސައްކަތެއް ނުކުރެވޭ ވަރަށް) އޭނާއަށް މުސްކުޅިކަން އައިސްފައިވަނިކޮށް، ދެން، އަލިފާންހުރި ވައިގެ ގަދަ ކޮޅިގަނޑެއް އެ ބަގީޗާއަށްޖެހި އަނދައިގެންދާ ބަގީޗާއެއް އޮތުމަށް، ތިޔަބައިމީހުންކުރެ އެކަކުވެސް ހިތްއެދޭނެ ހެއްޔެވެ؟ އެފަދައިން، ތިޔަބައިމީހުންނަށް، ﷲ، އާޔަތްތައް ބަޔާންކޮށްދެއްވަނީ ތިޔަބައިމީހުން ފިކުރު ކުޅައުމަށްޓަކައެވެ.","",""],["₂ سورة البقرة","267","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ أَنفِقُواْ مِن طَيِّبَٰتِ مَا كَسَبۡتُمۡ وَمِمَّآ أَخۡرَجۡنَا لَكُم مِّنَ ٱلۡأَرۡضِۖ وَلَا تَيَمَّمُواْ ٱلۡخَبِيثَ مِنۡهُ تُنفِقُونَ وَلَسۡتُم بِـَٔاخِذِيهِ إِلَّآ أَن تُغۡمِضُواْ فِيهِۚ وَٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ غَنِيٌّ حَمِيدٌ ٢٦٧","يا أيها الذين آمنوا أنفقوا من طيبات ما كسبتم ومما أخرجنا لكم من الأرض ولا تيمموا الخبيث منه تنفقون ولستم بآخذيه إلا أن تغمضوا فيه واعلموا أن الله غني حميد","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ހޯދިތަކެތީގެ ތެރެއިން ރަނގަޅު ތަކެތިން ތިޔަބައިމީހުން ހޭދަކުރާށެވެ! އަދި، ތިޔަބައިމީހުންނަށްޓަކައި ބިމުން ތިމަންރަސްކަލާނގެ ނެރެދެއްވި ތަކެތިންވެސް މެއެވެ. އަދި، އެއިން ހޭދަކުރުމަށްޓަކައި، ދެރަ ތަކެތި ގަސްދު ނުކުރާށެވެ! ތިޔަބައިމީހުން (އެފަދަ ތަކެތީގައި ހިފާންޖެހޭ މީހުން ކަމުގައިވާނަމަ) އެ ތަކެއްޗާމެދު ނުރުހުންވެ ލޯމަރައިގެން ނޫނީ އެ ތަކެތީގައި ތިޔަބައިމީހުންވެސް ނުހިފާނޫއެވެ. ހަމަކަށަވަރުން، ﷲއީ، ފުދިވޮޑިގެންވާ، ގިނަގިނައިން ހަމްދު ލިބިވޮޑިގެންވާ ރަސްކަލާނގެކަން ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₂ سورة البقرة","268","ٱلشَّيۡطَٰنُ يَعِدُكُمُ ٱلۡفَقۡرَ وَيَأۡمُرُكُم بِٱلۡفَحۡشَآءِۖ وَٱللَّهُ يَعِدُكُم مَّغۡفِرَةٗ مِّنۡهُ وَفَضۡلٗاۗ وَٱللَّهُ وَٰسِعٌ عَلِيمٞ ٢٦٨","الشيطان يعدكم الفقر ويأمركم بالفحشاء والله يعدكم مغفرة منه وفضلا والله واسع عليم","ފަގީރު ވެދާނޭ ކަމުގެ ބިރުން، ތިޔަބައިމީހުންނަށް ޝައިތާނާ ބިރުދައްކަތެވެ. އަދި، އެ ޝައިތާނާ ތިޔަބައިމީހުންނަށް ނުބައިކަންތަކަށް އަމުރު ކުރެތެވެ. ﷲ، ތިޔަބައިމީހުންނަށް ވައުދުކުރައްވަނީ، އެކަލާނގެ ހަޒުރަތުން ތިޔަބައިމީހުންނަށް ފާފަފުއްސެވުމާއި، ފަޟްލުވަންތަ ކަމަށެވެ. ﷲއީ، ތަނަވަސްވަންތަ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","269","يُؤۡتِي ٱلۡحِكۡمَةَ مَن يَشَآءُۚ وَمَن يُؤۡتَ ٱلۡحِكۡمَةَ فَقَدۡ أُوتِيَ خَيۡرٗا كَثِيرٗاۗ وَمَا يَذَّكَّرُ إِلَّآ أُوْلُواْ ٱلۡأَلۡبَٰبِ ٢٦٩","يؤتي الحكمة من يشاء ومن يؤت الحكمة فقد أوتي خيرا كثيرا وما يذكر إلا أولو الألباب","އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ހިކުމަތް ދެއްވައެވެ. އަދި، (އެމީހަކަށް) ހިކުމަތް ދެއްވި މީހާއަށް ފަހެ، ގިނަވެގެންވާ ހެޔޮކަން ލިބިއްޖެކަން ކަށަވަރެވެ. ބުއްދީގެ އަހުލުވެރިން މެނުވީ، ވިސްނައި ހަނދުމަކޮށެއް ނަހަދަތެވެ.","",""],["₂ سورة البقرة","270","وَمَآ أَنفَقۡتُم مِّن نَّفَقَةٍ أَوۡ نَذَرۡتُم مِّن نَّذۡرٖ فَإِنَّ ٱللَّهَ يَعۡلَمُهُۥۗ وَمَا لِلظَّـٰلِمِينَ مِنۡ أَنصَارٍ ٢٧٠","وما أنفقتم من نفقة أو نذرتم من نذر فإن الله يعلمه وما للظالمين من أنصار","އަދި، ހޭދަކުރުމުގެ ތެރެއިން ތިޔަބައިމީހުންކުރި ހޭދައެއް، ނުވަތަ، ނަދުރުގެ ތެރެއިން ތިޔަބައިމީހުން ގަތް ނަދުރެއް، ހަމަކަށަވަރުން، ﷲ ދެނެވޮޑިގެންވެއެވެ. އަނިޔާވެރިންނަށް ނަސްރު ދޭނޭ އެއްވެސް ބަޔަކު ނުވެއެވެ.","",""],["₂ سورة البقرة","271","إِن تُبۡدُواْ ٱلصَّدَقَٰتِ فَنِعِمَّا هِيَۖ وَإِن تُخۡفُوهَا وَتُؤۡتُوهَا ٱلۡفُقَرَآءَ فَهُوَ خَيۡرٞ لَّكُمۡۚ وَيُكَفِّرُ عَنكُم مِّن سَيِّـَٔاتِكُمۡۗ وَٱللَّهُ بِمَا تَعۡمَلُونَ خَبِيرٞ ٢٧١","إن تبدوا الصدقات فنعما هي وإن تخفوها وتؤتوها الفقراء فهو خير لكم ويكفر عنكم من سيئاتكم والله بما تعملون خبير","(ވާޖިބު ނޫން) ސަދަގާތްތައް، ތިޔަބައިމީހުން ފާޅުގައި ދެނީނަމަ، ފަހެ، އެއީ ނުހަނު މޮޅު ކަމެކެވެ. އަދި، ތިޔަބައިމީހުން ވަންހަނާކޮށް، އެ ސަދަގާތްތައް ފަގީރުންނަށް ދެނީނަމަ، ތިޔަބައިމީހުންނަށް އެކަމުގެ ހެޔޮކަން މާބޮޑެވެ. އަދި، އެއީ، ތިޔަބައިމީހުންގެ ކުށްތަކުން ބައެއް ތިޔަބައިމީހުންގެ ކިބައިން އެކަލާނގެ ފުއްސަވާނޭ ކަމެކެވެ. ﷲއީ، ތިޔަބައިމީހުންކުރާ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","272","۞لَّيۡسَ عَلَيۡكَ هُدَىٰهُمۡ وَلَٰكِنَّ ٱللَّهَ يَهۡدِي مَن يَشَآءُۗ وَمَا تُنفِقُواْ مِنۡ خَيۡرٖ فَلِأَنفُسِكُمۡۚ وَمَا تُنفِقُونَ إِلَّا ٱبۡتِغَآءَ وَجۡهِ ٱللَّهِۚ وَمَا تُنفِقُواْ مِنۡ خَيۡرٖ يُوَفَّ إِلَيۡكُمۡ وَأَنتُمۡ لَا تُظۡلَمُونَ ٢٧٢","ليس عليك هداهم ولكن الله يهدي من يشاء وما تنفقوا من خير فلأنفسكم وما تنفقون إلا ابتغاء وجه الله وما تنفقوا من خير يوف إليكم وأنتم لا تظلمون","އެއުރެންނަށް ތެދުމަގު ދެއްކެވުމަކީ، ކަލޭގެފާނަށް އޮތްކަމެއް ނޫނެވެ. (ކަލޭގެފާނަށްއޮތީ އިއްވެވުމެވެ.) އެހެނެއްކަމަކު، ﷲ، އެކަލާނގެ އިރާދަކުރެއްވި މީހަކަށް ތެދުމަގު ދައްކަވައެވެ. އަދި، ތިޔަބައިމީހުން މުދަލުގެ ތެރެއިން ހޭދަކުރާ އެއްޗެއް (ގެ ސަވާބު) ލިބޭހުށީ، ހަމަ ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސު ތަކަށެވެ. އަދި، ﷲގެ ވަޖުހުފުޅު އެދިގެން މެނުވީ، ތިޔަބައިމީހުން ހޭދައެއް ނުކުރަމުއެވެ. އަދި، މުދަލުން ތިޔަބައިމީހުން ހޭދަކުރާ އެއްޗެއް (ގެ ސަވާބާއި ދަރުމަ) ފުރިހަމައަށް ތިޔަބައި މީހުންނަށް ލިބޭނެތެވެ. އަދި، ތިޔަބައިމީހުންނަށް ބޭއިންސާފެއް ނުކުރައްވާ ހުށްޓެވެ.","",""],["₂ سورة البقرة","273","لِلۡفُقَرَآءِ ٱلَّذِينَ أُحۡصِرُواْ فِي سَبِيلِ ٱللَّهِ لَا يَسۡتَطِيعُونَ ضَرۡبٗا فِي ٱلۡأَرۡضِ يَحۡسَبُهُمُ ٱلۡجَاهِلُ أَغۡنِيَآءَ مِنَ ٱلتَّعَفُّفِ تَعۡرِفُهُم بِسِيمَٰهُمۡ لَا يَسۡـَٔلُونَ ٱلنَّاسَ إِلۡحَافٗاۗ وَمَا تُنفِقُواْ مِنۡ خَيۡرٖ فَإِنَّ ٱللَّهَ بِهِۦ عَلِيمٌ ٢٧٣","للفقراء الذين أحصروا في سبيل الله لا يستطيعون ضربا في الأرض يحسبهم الجاهل أغنياء من التعفف تعرفهم بسيماهم لا يسألون الناس إلحافا وما تنفقوا من خير فإن الله به عليم","ﷲގެ މަގުގައި (ޖިހާދުކުރުމުގައި) ބަންދުވެފައި ތިބި ފަގީރުންނަށް (ސަދަގާތް ދިނުން) ހުށްޓެވެ. އެއުރެންނަކަށް (ދިރިއުޅުމުގެ މަސައްކަތް ކުރުމަށް) ބިމުގައި ދަތުރުފަތުރުކޮށެއް ނޫޅެވެއެވެ. އެއުރެންގެ ޚަބަރު ނުދަންނަ މީހާ ހީކުރަނީ، އެއްޗިއްސަށް ނޭދުމުގެ ސަބަބުން، އެއީ، މުއްސަނދިން ކަމަށެވެ. އެއުރެންގެ އަލާމަތް ތަކުން، ތިބާޔަށް އެއުރެން އެނގޭނެތެވެ. އެއުރެން އެއްޗިއްސަށްއެދި، މީހުންނަށް އާދޭސްކޮށެއް ނޫޅޭނެތެވެ. ތިޔަބައިމީހުން މުދަލުން ހޭދަކުރާ ކޮންމެ އެއްޗަކާމެދު (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲ، އެކަންތައް މޮޅަށް ދެނެވޮޑިގެންވެއެވެ.","",""],["₂ سورة البقرة","274","ٱلَّذِينَ يُنفِقُونَ أَمۡوَٰلَهُم بِٱلَّيۡلِ وَٱلنَّهَارِ سِرّٗا وَعَلَانِيَةٗ فَلَهُمۡ أَجۡرُهُمۡ عِندَ رَبِّهِمۡ وَلَا خَوۡفٌ عَلَيۡهِمۡ وَلَا هُمۡ يَحۡزَنُونَ ٢٧٤","الذين ينفقون أموالهم بالليل والنهار سرا وعلانية فلهم أجرهم عند ربهم ولا خوف عليهم ولا هم يحزنون","އެއުރެންނީ، ރެއާއިދުވާލު، ސިއްރާއި ފާޅުގައި، އެއުރެންގެ މުދާތައް ހޭދަކުރާ މީހުންނެވެ. ފަހެ، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި އެއުރެންގެ ދަރުމަ، އެއުރެންނަށް ހުށްޓެވެ. އަދި، އެއުރެންގެ މައްޗަކަށް ބިރެއް ނެތެވެ. އަދި ހިތާމަކުރާނޭ ބަޔަކުކަމުގައިވެސް އެއުރެން ނުމެވޭމެއެވެ.","",""],["₂ سورة البقرة","275","ٱلَّذِينَ يَأۡكُلُونَ ٱلرِّبَوٰاْ لَا يَقُومُونَ إِلَّا كَمَا يَقُومُ ٱلَّذِي يَتَخَبَّطُهُ ٱلشَّيۡطَٰنُ مِنَ ٱلۡمَسِّۚ ذَٰلِكَ بِأَنَّهُمۡ قَالُوٓاْ إِنَّمَا ٱلۡبَيۡعُ مِثۡلُ ٱلرِّبَوٰاْۗ وَأَحَلَّ ٱللَّهُ ٱلۡبَيۡعَ وَحَرَّمَ ٱلرِّبَوٰاْۚ فَمَن جَآءَهُۥ مَوۡعِظَةٞ مِّن رَّبِّهِۦ فَٱنتَهَىٰ فَلَهُۥ مَا سَلَفَ وَأَمۡرُهُۥٓ إِلَى ٱللَّهِۖ وَمَنۡ عَادَ فَأُوْلَـٰٓئِكَ أَصۡحَٰبُ ٱلنَّارِۖ هُمۡ فِيهَا خَٰلِدُونَ ٢٧٥","الذين يأكلون الربا لا يقومون إلا كما يقوم الذي يتخبطه الشيطان من المس ذلك بأنهم قالوا إنما البيع مثل الربا وأحل الله البيع وحرم الربا فمن جاءه موعظة من ربه فانتهى فله ما سلف وأمره إلى الله ومن عاد فأولئك أصحاب النار هم فيها خالدون","ރިބާ ކާމީހުން، ޖިންނި މޮޔަވެގެން، ޝައިތާނާ ތަޅުވަމުން ފޮޅުވަމުން ގެންދާ މީހަކު ތެދުވާ ފަދައިން މެނުވީ (ގިޔާމަތް ދުވަހުން އެއުރެން ކަށްވަޅުން) ނުތެދުވާނެތެވެ. އެހެނީ، އެއުރެން ބުނެއުޅުނީ، ވިޔަފާރި ވާކަން ކަށަވަރީ، ރިބާ ކަހަލަކަމެއް ކަމުގައެވެ. (ނަމަވެސް) ވިޔަފާރި ކުރުންވަނީ، ﷲ، ހުއްދަ ކުރައްވާފައެވެ. އަދި، ރިބާ ވަނީ ހަރާމްކުރައްވާފައެވެ. ފަހެ، އެމީހާގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ދެއްވާ ވައުޒާއި ނަސޭހަތް، އެމީހަކާ ހަމަޔަށް އައުމުން އެކަން (އެބަހީ: ރިބާ ކެއުން) ހުއްޓާލައިފި މީހާ (ދަންނާށެވެ!) ފަހެ، އިސްވެދިޔަ އެއްޗެއް އެމީހަކަށް ހުށްޓެވެ. (އެބަހީ: ރިބާގެ ހުކުމްތައް އައުމުގެ ކުރިން އޭނާ ބޭނުންކުރި ތަކެތި މާފުކުރައްވާފައި ވެއެވެ.) އަދި، އެމީހެއްގެ ކަންތައްއޮތީ، ﷲއަށް ހާއްސަ ވެގެންނެވެ. އަދި، އަލުން (އެކަމަށް) އެނބުރި އަތުވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ ނަރަކައިގެ އަހުލުވެރިންނެވެ. އެއުރެންނީ އެތާނގައި ދެމިތިބެނިވި ބަޔެކެވެ.","",""],["₂ سورة البقرة","276","يَمۡحَقُ ٱللَّهُ ٱلرِّبَوٰاْ وَيُرۡبِي ٱلصَّدَقَٰتِۗ وَٱللَّهُ لَا يُحِبُّ كُلَّ كَفَّارٍ أَثِيمٍ ٢٧٦","يمحق الله الربا ويربي الصدقات والله لا يحب كل كفار أثيم","ﷲ، ރިބާ އުނިކުރައްވައި، އޭގެ ބަރަކާތް ނެތިކުރައްވައެވެ. އަދި، ސަދަގާތް އިތުރު ކުރައްވައެވެ. (އެބަހީ: ދުނިޔޭގައި އޭގެ ބަރަކާތް އިތުރު ކުރައްވައި، އާޚިރަތުގައި އޭގެ ދަރުމަ ގިނަގުނަ ކުރައްވައެވެ.) އަދި، ފާފަވެރި، ކޮންމެ ކާފިރަކު ދެކެ، ﷲ ލޯބިވެ ވޮޑިގެނެއް ނުވެއެވެ.","",""],["₂ سورة البقرة","277","إِنَّ ٱلَّذِينَ ءَامَنُواْ وَعَمِلُواْ ٱلصَّـٰلِحَٰتِ وَأَقَامُواْ ٱلصَّلَوٰةَ وَءَاتَوُاْ ٱلزَّكَوٰةَ لَهُمۡ أَجۡرُهُمۡ عِندَ رَبِّهِمۡ وَلَا خَوۡفٌ عَلَيۡهِمۡ وَلَا هُمۡ يَحۡزَنُونَ ٢٧٧","إن الذين آمنوا وعملوا الصالحات وأقاموا الصلاة وآتوا الزكاة لهم أجرهم عند ربهم ولا خوف عليهم ولا هم يحزنون","ހަމަކަށަވަރުން، އީމާންވެ، ސާލިހު ޢަމަލުތައް ކޮށް، ނަމާދު ގާއިމު ކޮށް، ޒަކާތް ދީ އުޅުނު މީހުންނަށް އެއުރެންގެ ދަރުމަ، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ވެއެވެ. އަދި، އެއުރެންގެ މައްޗަށް އެއްވެސް ބިރެއް ނެތެވެ. އަދި، އެއުރެންނަކީ، ހިތާމަ ކުރާނޭ ބަޔަކު ކަމުގައިވެސް ނުމެވޭމެއެވެ.","",""],["₂ سورة البقرة","278","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ ٱتَّقُواْ ٱللَّهَ وَذَرُواْ مَا بَقِيَ مِنَ ٱلرِّبَوٰٓاْ إِن كُنتُم مُّؤۡمِنِينَ ٢٧٨","يا أيها الذين آمنوا اتقوا الله وذروا ما بقي من الربا إن كنتم مؤمنين","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ﷲއަށް ތިޔަބައިމީހުން ތަގުވާވެރިވާށެވެ! އަދި، ތިޔަބައިމީހުން މުއުމިނުން ކަމުގައިވާނަމަ، ރިބާގެ ތެރެއިން ބާކީ (ލިބޭން) ހުރި އެއްޗެއް ތިޔަބައިމީހުން ދޫކޮށްލާށެވެ!","",""],["₂ سورة البقرة","279","فَإِن لَّمۡ تَفۡعَلُواْ فَأۡذَنُواْ بِحَرۡبٖ مِّنَ ٱللَّهِ وَرَسُولِهِۦۖ وَإِن تُبۡتُمۡ فَلَكُمۡ رُءُوسُ أَمۡوَٰلِكُمۡ لَا تَظۡلِمُونَ وَلَا تُظۡلَمُونَ ٢٧٩","فإن لم تفعلوا فأذنوا بحرب من الله ورسوله وإن تبتم فلكم رءوس أموالكم لا تظلمون ولا تظلمون","ފަހެ، ތިޔަބައިމީހުން (ނަށް އަމުރު ވެވިގެންވާ ގޮތަށް) ޢަމަލު ނުކޮށްފިނަމަ، ﷲއާއި، އެކަލާނގެ ރަސޫލާގެ ހަޒުރަތުން ހަނގުރާމައެއް އަތުވެދާނެކަމަށް ތިޔަބައިމީހުން ޔަގީން ކޮށް ދެނެގަންނަ ހުށިކަމެވެ! ތިޔަބައިމީހުން (ރިބާ ދޫކޮށް) އެނބުރި ރުޖޫއަވެ ތައުބާ ވެއްޖެނަމަ ތިޔަބައިމީހުންގެ ރައުސުލް މާލްތައް، ފަހެ، ތިޔަބައިމީހުންނަށް ހުށްޓެވެ. (އިތުރުކޮށްގެން) ތިޔަބައިމީހުން އަނިޔާވެރި ނުވާ ގޮތުގައެވެ. އަދި، (އުނިވުމުން) ތިޔަބައިމީހުންނަށްވެސް އަނިޔާ ނުލިބޭ ގޮތުގައެވެ.","",""],["₂ سورة البقرة","280","وَإِن كَانَ ذُو عُسۡرَةٖ فَنَظِرَةٌ إِلَىٰ مَيۡسَرَةٖۚ وَأَن تَصَدَّقُواْ خَيۡرٞ لَّكُمۡ إِن كُنتُمۡ تَعۡلَمُونَ ٢٨٠","وإن كان ذو عسرة فنظرة إلى ميسرة وأن تصدقوا خير لكم إن كنتم تعلمون","އަދި، (ދަރަނިވެރިޔާއަކީ) އަތްމަތި ދަތި މީހަކު ކަމުގައިވާނަމަ، ފަހެ، (އެމީހާއަށް) ތަނަވަސްކަމެއް ލިބެންދެން (އޭނާއަށް) މުހުލަތް ދޭ ހުށިކަމެވެ! އަދި، ތިޔަބައިމީހުން (އެ ދަރަނީން) ސަދަގާތްކުރުން (އެބަހީ: އެ ދަރަނި މާފުކުރުން) ތިޔަބައިމީހުންނަށް ހެޔޮކަން ބޮޑެވެ. ތިޔަބައިމީހުންނަށް (އެކަން) އެނގޭ ކަމުގައި ވާނަމައެވެ.","",""],["₂ سورة البقرة","281","وَٱتَّقُواْ يَوۡمٗا تُرۡجَعُونَ فِيهِ إِلَى ٱللَّهِۖ ثُمَّ تُوَفَّىٰ كُلُّ نَفۡسٖ مَّا كَسَبَتۡ وَهُمۡ لَا يُظۡلَمُونَ ٢٨١","واتقوا يوما ترجعون فيه إلى الله ثم توفى كل نفس ما كسبت وهم لا يظلمون","އެދުވަހެއްގައި، ﷲގެ ހަޒުރަތަށް ތިޔަބައިމީހުން ރުޖޫއަކުރައްވާނޭ ދުވަހަކަށް، ތިޔަބައިމީހުން ރައްކާތެރިވެ ބިރުވެތިވާށެވެ! ދެން، ކޮންމެ ނަފްސަކަށްމެ، އެ ނަފްސެއް ހޯދި ކަމެއްގެ ޖަޒާ (އެދުވަހުން) ލިބޭނެތެވެ. އަދި، އެއުރެންނަށް ބޭއިންސާފެއް ނުކުރައްވާ ހުށްޓެވެ.","",""],["₂ سورة البقرة","282","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ إِذَا تَدَايَنتُم بِدَيۡنٍ إِلَىٰٓ أَجَلٖ مُّسَمّٗى فَٱكۡتُبُوهُۚ وَلۡيَكۡتُب بَّيۡنَكُمۡ كَاتِبُۢ بِٱلۡعَدۡلِۚ وَلَا يَأۡبَ كَاتِبٌ أَن يَكۡتُبَ كَمَا عَلَّمَهُ ٱللَّهُۚ فَلۡيَكۡتُبۡ وَلۡيُمۡلِلِ ٱلَّذِي عَلَيۡهِ ٱلۡحَقُّ وَلۡيَتَّقِ ٱللَّهَ رَبَّهُۥ وَلَا يَبۡخَسۡ مِنۡهُ شَيۡـٔٗاۚ فَإِن كَانَ ٱلَّذِي عَلَيۡهِ ٱلۡحَقُّ سَفِيهًا أَوۡ ضَعِيفًا أَوۡ لَا يَسۡتَطِيعُ أَن يُمِلَّ هُوَ فَلۡيُمۡلِلۡ وَلِيُّهُۥ بِٱلۡعَدۡلِۚ وَٱسۡتَشۡهِدُواْ شَهِيدَيۡنِ مِن رِّجَالِكُمۡۖ فَإِن لَّمۡ يَكُونَا رَجُلَيۡنِ فَرَجُلٞ وَٱمۡرَأَتَانِ مِمَّن تَرۡضَوۡنَ مِنَ ٱلشُّهَدَآءِ أَن تَضِلَّ إِحۡدَىٰهُمَا فَتُذَكِّرَ إِحۡدَىٰهُمَا ٱلۡأُخۡرَىٰۚ وَلَا يَأۡبَ ٱلشُّهَدَآءُ إِذَا مَا دُعُواْۚ وَلَا تَسۡـَٔمُوٓاْ أَن تَكۡتُبُوهُ صَغِيرًا أَوۡ كَبِيرًا إِلَىٰٓ أَجَلِهِۦۚ ذَٰلِكُمۡ أَقۡسَطُ عِندَ ٱللَّهِ وَأَقۡوَمُ لِلشَّهَٰدَةِ وَأَدۡنَىٰٓ أَلَّا تَرۡتَابُوٓاْ إِلَّآ أَن تَكُونَ تِجَٰرَةً حَاضِرَةٗ تُدِيرُونَهَا بَيۡنَكُمۡ فَلَيۡسَ عَلَيۡكُمۡ جُنَاحٌ أَلَّا تَكۡتُبُوهَاۗ وَأَشۡهِدُوٓاْ إِذَا تَبَايَعۡتُمۡۚ وَلَا يُضَآرَّ كَاتِبٞ وَلَا شَهِيدٞۚ وَإِن تَفۡعَلُواْ فَإِنَّهُۥ فُسُوقُۢ بِكُمۡۗ وَٱتَّقُواْ ٱللَّهَۖ وَيُعَلِّمُكُمُ ٱللَّهُۗ وَٱللَّهُ بِكُلِّ شَيۡءٍ عَلِيمٞ ٢٨٢","يا أيها الذين آمنوا إذا تداينتم بدين إلى أجل مسمى فاكتبوه وليكتب بينكم كاتب بالعدل ولا يأب كاتب أن يكتب كما علمه الله فليكتب وليملل الذي عليه الحق وليتق الله ربه ولا يبخس منه شيئا فإن كان الذي عليه الحق سفيها أو ضعيفا أو لا يستطيع أن يمل هو فليملل وليه بالعدل واستشهدوا شهيدين من رجالكم فإن لم يكونا رجلين فرجل وامرأتان ممن ترضون من الشهداء أن تضل إحداهما فتذكر إحداهما الأخرى ولا يأب الشهداء إذا ما دعوا ولا تسأموا أن تكتبوه صغيرا أو كبيرا إلى أجله ذلكم أقسط عند الله وأقوم للشهادة وأدنى ألا ترتابوا إلا أن تكون تجارة حاضرة تديرونها بينكم فليس عليكم جناح ألا تكتبوها وأشهدوا إذا تبايعتم ولا يضار كاتب ولا شهيد وإن تفعلوا فإنه فسوق بكم واتقوا الله ويعلمكم الله والله بكل شيء عليم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ކަނޑައެޅި އެނގިގެންވާ މުއްދަތަކަށް، ތިޔަބައިމީހުން ދަރަންޏެއްގެ މުޢާމަލާތެއް ކޮށްފިނަމަ، ފަހެ، އެ ދަރަންޏެއް ތިޔަބައިމީހުން ލިޔާށެވެ! އަދި، ތިޔަބައިމީހުންގެ މެދުގައި ލިޔާ މީހަކު ޢަދުލުވެރި ކަމާއެކު (އުނި އިތުރު ކުރުމެއް ނެތި، އެއުރެން އެއްބަސްވީގޮތަށް، އެ ދަރަނީގެ ލިޔުން) ލިޔާހުށި ކަމެވެ! ލިޔާ މީހަކު (ކިބައިން ލިޔެދިނުމަށް އެދިއްޖެނަމަ) އޭނާއަށް، ﷲ ލިޔަން އުނގަންނައިދެއްވި ފަދައިން ލިޔެދިނުމުން، އޭނާ މަނާވެ ނުގަންނަހުށި ކަމެވެ! ފަހެ، އޭނާ ލިޔާހުށި ކަމެވެ! އަދި، އެމީހެއްގެ މައްޗަށް ހައްގު އޮތް މީހާ (އެބަހީ: ދަރަނިވެރިޔާ ލިޔަންވީ އެއްޗެއް ލިޔާ މީހާއަށް) ކިޔައިދޭހުށިކަމެވެ! އަދި، އޭނާގެ ވެރިރަސްކަލާނގެ ކަމުގައިވާ ﷲއަށް، އޭނާ ތަގުވާވެރި ވާހުށިކަމެވެ! އަދި، އެއިން އެއްވެސް އެއްޗެއް އުނި ނުކުރާ ހުށިކަމެވެ! ފަހެ، އެމީހެއްގެ މައްޗަށް ހައްގު އޮތް މީހާއީ (އެބަހީ: ދަރަނިވެރިޔާއީ) ދޯދިޔާ މީހަކު ކަމުގައިވާނަމަ (އެބަހީ: ވިޔާނުދާ ޚަރަދު ކޮށް އިސްރާފު ކޮށްއުޅޭ، އުޅުންގޯސް މީހަކު ކަމުގައިވާނަމަ) ނުވަތަ (ދަރަނިވެރިޔާއީ) ނިކަމެއްޗެއް ކަމުގައިވާނަމަ، (އެބަހީ: ކުޑަކުއްޖަކު، ނުވަތަ މޮޔައަކުފަދަ މީހަކު ކަމުގައިވާނަމަ) ނުވަތަ (ދަރަނިވެރިޔާއީ) އޭނާ އަމިއްލައަށް ކިޔައިދޭން ކުޅަދާނަކަން ލިބިގެންނުވާ މީހަކު ކަމުގައިވާނަމަ، ފަހެ، ޢަދުލުވެރިކަމާއެކު އޭނާގެ ވަލީވެރިޔާ (އެ ދަރަނި ލިޔުމަށް) ކިޔައިދޭ ހުށިކަމެވެ! އަދި، (މިފަދަ ކަންކަމުގައި) ތިޔަބައިމީހުންގެ ފިރިހެނުންގެ ތެރެއިން ދެހެކިން ތިޔަބައިމީހުން ހެކިކުރާށެވެ! އެ ދެ ހެކިންނަކީ، ދެފިރިހެނުން ކަމުގައި ނުވިނަމަ ފަހެ، ހެކިންކުރެ ތިޔަބައިމީހުން ރުހޭ މީހުންގެ ތެރެއިން (އެބަހީ: ޢަދުލުވެރި މުސްލިމުންގެ ތެރެއިން) ފިރިހެނަކާއި ދެ އަންހެނުންނެވެ. (އެއީ) އެ ދެ އަންހެނުންކުރެ އެކަކަށް (ހަނދާންނެތިވެ) މަގުއޮޅިދާނެ ކަމަށްޓަކައެވެ. ދެން، އެހިނދު އެ ދެ އަންހެނުންކުރެ އެކަކަށް، އަނެކަކު (އެކަން) ހަނދާންކޮށް ދިނުމަށްޓަކައެވެ. އަދި، ހެކިންނަށް ގޮވައިލައިފި ހިނދަކު އެއުރެން (އެކަމުން) މަނާވެ ނުގަންނަހުށިކަމެވެ! އަދި (އެ ދަރަނި) ކުޑަކަމުގައިވިޔަސް، ނުވަތަ ބޮޑު ކަމުގައިވިޔަސް އެ ދަރަނީގެ މުއްދަތާ ހަމަޔަށް ލިޔުމަށް، ތިޔަބައިމީހުން ފޫހިނުވާށެވެ! އެގޮތަށް ލިޔުން، ﷲގެ ހަޒުރަތުގައި ޢަދުލުވެރިކަން ބޮޑެވެ. އަދި، ހެކި ދިނުމަށް ސީދާކަން ބޮޑެވެ. އަދި، ތިޔަބައިމީހުންނަށް ޝައްކު ނުވުން ގާތްކަން ބޮޑުވެސްމެއެވެ. ތިޔަބައިމީހުންގެ މެދުގައި، ވަގުތުން ހިންގާ ވިޔަފާރިއެއް ކަމުގައި ވުމުން މެނުވީއެވެ. ފަހެ، ތިޔަބައިމީހުން އެ ވިޔަފާރި ނުލިޔުމުގައި ތިޔަބައިމީހުންގެ މައްޗަކަށް ކުށެއް ނެތެވެ. އަދި، ތިޔަބައިމީހުން ވިޔަފާރިއެއް ކޮށްފިނަމަ، ތިޔަބައިމީހުން ހެކިކުރާށެވެ! އަދި، ލިޔާ މީހާއާއި ހެކިދޭ މީހާ (ދަރަނިވެރިޔާއަށާއި ދަރަނިދޭ މީހާއަށް) ގެއްލުންނުދޭހުށި ކަމެވެ! (ނުވަތަ، އެ ދެ މީހުންނަށްވެސް ގެއްލުމެއް ލިބިގެން ނުވާހުށްޓެވެ.) ތިޔަބައިމީހުން (ނަށް ނަހީކުރެއްވި ކަންތައް) ކުރާނަމަ، ފަހެ، ހަމަކަށަވަރުން، އެއީ، ތިޔަބައިމީހުންގެ ކިބައިގައިވާ (ނުކިޔަމަންތެރި) ފާސިގުކަމެކެވެ. ތިޔަބައިމީހުން، ﷲއަށް ތަގުވާވެރިވާށެވެ! ﷲ، ތިޔަބައިމީހުންނަށް އުނގަންނައިދެއްވާނެއެވެ. ﷲއީ، ކޮންމެކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","283","۞وَإِن كُنتُمۡ عَلَىٰ سَفَرٖ وَلَمۡ تَجِدُواْ كَاتِبٗا فَرِهَٰنٞ مَّقۡبُوضَةٞۖ فَإِنۡ أَمِنَ بَعۡضُكُم بَعۡضٗا فَلۡيُؤَدِّ ٱلَّذِي ٱؤۡتُمِنَ أَمَٰنَتَهُۥ وَلۡيَتَّقِ ٱللَّهَ رَبَّهُۥۗ وَلَا تَكۡتُمُواْ ٱلشَّهَٰدَةَۚ وَمَن يَكۡتُمۡهَا فَإِنَّهُۥٓ ءَاثِمٞ قَلۡبُهُۥۗ وَٱللَّهُ بِمَا تَعۡمَلُونَ عَلِيمٞ ٢٨٣","وإن كنتم على سفر ولم تجدوا كاتبا فرهان مقبوضة فإن أمن بعضكم بعضا فليؤد الذي اؤتمن أمانته وليتق الله ربه ولا تكتموا الشهادة ومن يكتمها فإنه آثم قلبه والله بما تعملون عليم","ތިޔަބައިމީހުން (ދަރަނީގެ މުޢާމަލާތެއް ކުރާހިނދު) ދަތުރެއްގެ މަތީގައިވެފައި ލިޔާނެ މީހަކު ތިޔަބައިމީހުންނަށް ނުލިބުނުނަމަ، ފަހެ، އަތުގައި ބާއްވާ ރަހުނެއް ދޭހުށިކަމެވެ! ފަހެ، ތިޔަބައިމީހުންކުރެ އެކަކު އަނެކަކާ އަމާނަތެއް ޙަވާލު ކޮށްފިނަމަ، ފަހެ، އެ އަމާނަތާ ޙަވާލުވި މީހާ، އޭނާގެ އަމާނަތް ރައްދުކުރާ ހުށިކަމެވެ! އަދި، އޭނާގެ ވެރިރަސްކަލާނގެ ކަމުގައިވާ ﷲއަށް، އޭނާ ތަގުވާވެރިވާހުށިކަމެވެ! އަދި ތިޔަބައިމީހުން ހެކިބަސް ވަންހަނާ ނުކުރާހުށިކަމެވެ! އެކަން ވަންހަނާކުރާ މީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އޭނާއީ، އޭނާގެ ހިތް ފާފަވެރިވެގެންވާ މީހެކެވެ. ﷲއީ، ތިޔަބައިމީހުންކުރާ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","284","لِّلَّهِ مَا فِي ٱلسَّمَٰوَٰتِ وَمَا فِي ٱلۡأَرۡضِۗ وَإِن تُبۡدُواْ مَا فِيٓ أَنفُسِكُمۡ أَوۡ تُخۡفُوهُ يُحَاسِبۡكُم بِهِ ٱللَّهُۖ فَيَغۡفِرُ لِمَن يَشَآءُ وَيُعَذِّبُ مَن يَشَآءُۗ وَٱللَّهُ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٌ ٢٨٤","لله ما في السماوات وما في الأرض وإن تبدوا ما في أنفسكم أو تخفوه يحاسبكم به الله فيغفر لمن يشاء ويعذب من يشاء والله على كل شيء قدير","އުޑުތަކުގައިވާހާ އެއްޗަކާއި، ބިމުގައިވާހާ އެއްޗެއް މިލްކުވެގެންވަނީ ﷲއަށެވެ. ތިޔަބައިމީހުންގެ ނަފްސު ތަކުގައިވާ އެއްޗެއް، ތިޔަބައިމީހުން ފާޅުކުޅަޔަސް، ނުވަތަ އެކަން ތިޔަބައިމީހުން ސިއްރު ކުޅަޔަސް އެކަމާމެދު، ﷲ، ތިޔަބައިމީހުންނާ (ސުވާލުކުރައްވައި) ހިސާބު ބައްލަވާނެއެވެ. ދެން، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ފާފަފުއްސަވާނެއެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް އަޒާބު ދެއްވާނެއެވެ. ﷲއީ، ކޮންމެ ކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₂ سورة البقرة","285","ءَامَنَ ٱلرَّسُولُ بِمَآ أُنزِلَ إِلَيۡهِ مِن رَّبِّهِۦ وَٱلۡمُؤۡمِنُونَۚ كُلٌّ ءَامَنَ بِٱللَّهِ وَمَلَـٰٓئِكَتِهِۦ وَكُتُبِهِۦ وَرُسُلِهِۦ لَا نُفَرِّقُ بَيۡنَ أَحَدٖ مِّن رُّسُلِهِۦۚ وَقَالُواْ سَمِعۡنَا وَأَطَعۡنَاۖ غُفۡرَانَكَ رَبَّنَا وَإِلَيۡكَ ٱلۡمَصِيرُ ٢٨٥","آمن الرسول بما أنزل إليه من ربه والمؤمنون كل آمن بالله وملائكته وكتبه ورسله لا نفرق بين أحد من رسله وقالوا سمعنا وأطعنا غفرانك ربنا وإليك المصير","ރަސޫލާއަށް، އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ބާވައިލެއްވި އެއްޗަކަށް (އެބަހީ: ކީރިތި ގުރްއާނަށް) ރަސޫލާއާއި މުއުމިނުން އީމާން ވިއެވެ. އެ އެންމެންމެ ﷲއާއި، އެކަލާނގެ މަލާއިކަތްނާއި، އެކަލާނގެ (ބާވައިލެއްވި) ފޮތްތަކާއި، އެކަލާނގެ ފޮނުއްވި ރަސޫލުންނަށް އީމާން ވިއެވެ. (އެއުރެން ބުނެތެވެ.) ތިމަންމެން، އެކަލާނގެ ރަސޫލުންގެ ތެރެއިން އެކަކާމެދުވެސް ތަފާތެއް ނުކުރަމުއެވެ. އަދި، އެއުރެން ބުނޫއެވެ. ތިމަންމެން އަހައި ކިޔަމަންވެއްޖައީމުއެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! އަޅަމެންގެ ފާފަފުއްސަވައިފާނދޭވެއެވެ! އަދި، އެނބުރި ދިއުންވަނީ، އިބަރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["₂ سورة البقرة","286","لَا يُكَلِّفُ ٱللَّهُ نَفۡسًا إِلَّا وُسۡعَهَاۚ لَهَا مَا كَسَبَتۡ وَعَلَيۡهَا مَا ٱكۡتَسَبَتۡۗ رَبَّنَا لَا تُؤَاخِذۡنَآ إِن نَّسِينَآ أَوۡ أَخۡطَأۡنَاۚ رَبَّنَا وَلَا تَحۡمِلۡ عَلَيۡنَآ إِصۡرٗا كَمَا حَمَلۡتَهُۥ عَلَى ٱلَّذِينَ مِن قَبۡلِنَاۚ رَبَّنَا وَلَا تُحَمِّلۡنَا مَا لَا طَاقَةَ لَنَا بِهِۦۖ وَٱعۡفُ عَنَّا وَٱغۡفِرۡ لَنَا وَٱرۡحَمۡنَآۚ أَنتَ مَوۡلَىٰنَا فَٱنصُرۡنَا عَلَى ٱلۡقَوۡمِ ٱلۡكَٰفِرِينَ ٢٨٦","لا يكلف الله نفسا إلا وسعها لها ما كسبت وعليها ما اكتسبت ربنا لا تؤاخذنا إن نسينا أو أخطأنا ربنا ولا تحمل علينا إصرا كما حملته على الذين من قبلنا ربنا ولا تحملنا ما لا طاقة لنا به واعف عنا واغفر لنا وارحمنا أنت مولانا فانصرنا على القوم الكافرين","ﷲ، އެއްވެސް ނަފްސަކަށް، އެ ނަފްސަކަށް ކުޅަދާނަވެގެންވާ ކަމަކަށް މެނުވީ ތަކުލީފެއް ނުޖައްސަވައެވެ. އެ ނަފްސެއް ހޯދި ހެޔޮކަމެއް (ގެ ސަވާބު) އެ ނަފްސަކަށް ވެއެވެ. އަދި، އެ ނަފްސެއް ހޯދި ނުބައިކަމެއް (ގެ ޢިގާބު) އެ ނަފްސެއްގެ މައްޗަށްވެއެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެން ހަނދާންނެތިއްޖެނަމަ، ނުވަތަ، ގަސްދެއްނެތި އަޅަމެންނަށް ކުށެއް ވެވިއްޖެނަމަ (އެކަމަށް) އަޅަމެންނަށް އުގޫބާތް ނުދެއްވާނދޭވެ! އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެންގެ ކުރިންތިބި މީހުންނަށް އުފުލުމަށް ޖެއްސެވިފަދަ ބުރަކަމެއް އަޅަމެން އުފުލުމަށް ނުޖައްސަވާނދޭވެ! އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެންނަށް އެކަމަކަށް ކުޅަދާނަވެގެން ނުވާކަމެއް އުފުލުމަށް އަޅަމެންނަށް ނުޖައްސަވާނދޭވެ! އަދި، އަޅަމެންނަށް އަފޫކުރައްވާނދޭވެ! އަދި، އަޅަމެންނަށް ފާފަފުއްސަވާނދޭވެ! އަދި، އަޅަމެންނަށް ރަހުމަތް ލައްވާނދޭވެ! އިބަރަސްކަލާނގެއީ އަޅަމެންގެ އެހީތެރިވަންތަ ރަސްކަލާނގެއެވެ. ފަހެ، ކާފިރު ވެގެންވާ ގައުމުގެ މައްޗަށް އަޅަމެންނަށް ނަސްރު ދެއްވާނދޭވެ!","",""],["₃ سورة آل عمران","1","بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ\n<br><br>\nالٓمٓ ١","بسم الله الرحمن الرحيم الم","ا ل م (މި އަކުރުތަކާއި ބައެއް ސޫރަތް ފެށޭތާނގައިވާ އަލިފުބާގެ މިފަދަ އަކުރުތަކުގެ މާނައާމެދު، އިލްމުވެރިންގެ މެދުގައި ޚިލާފު ހުށްޓެވެ. ބައެއް އިލްމުވެރިން ވިދާޅުވަނީ، ކީރިތި ގުރްއާން އެކުލެވިގެންވަނީ، އަރަބީންގެ އެންމެން ވާހަކަ ދައްކައިއުޅޭ އަލިފުބާގެ މިފަދަ އަކުރުތަކުން ކަމުގައި ވުމާއެކުވެސް، އެ އަކުރުތަކަކީ، ގުރްއާންގެ އެންމެ ސޫރަތަކާ އެއްފަދަ އެއްޗެއް ކީއްކުރަންތޯ، އެންމެ އާޔަތަކާ އެއްފަދަ އެއްޗެއްވެސް، އެއުރެންނަށް ގެނެސްނުގަނެވޭނެކަމަށް ގޮންޖެއްސެވުމުގެގޮތުން އައިސްފައިވާ އަކުރުތަކެއް ކަމުގައެވެ.)","",""],["₃ سورة آل عمران","2","ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَ ٱلۡحَيُّ ٱلۡقَيُّومُ ٢","الله لا إله إلا هو الحي القيوم","ﷲއީ، އެކަލާނގެ ފިޔަވައި (ހައްގު ވެގެން އަޅުކަމެއްވެވޭ) އިލާހަކު ނުވާ ރަސްކަލާނގެއެވެ. ދިރިދެމިވޮޑިގެންވާ، ދާއިމަށް ގާއިމުވެ ވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","3","نَزَّلَ عَلَيۡكَ ٱلۡكِتَٰبَ بِٱلۡحَقِّ مُصَدِّقٗا لِّمَا بَيۡنَ يَدَيۡهِ وَأَنزَلَ ٱلتَّوۡرَىٰةَ وَٱلۡإِنجِيلَ ٣","نزل عليك الكتاب بالحق مصدقا لما بين يديه وأنزل التوراة والإنجيل","ކުރީގެ ފޮތްތައް ތެދުކުރާ ޙާލުގައި، ހައްގު ގޮތުގައި ކަލޭގެފާނަށް އެކަލާނގެ ފޮތް (އެބަހީ: ކީރިތި ގުރްއާން) ބާވައިލެއްވިއެވެ. އަދި ތައުރާތާއި އިންޖީލު ވެސް ބާވައިލެއްވިއެވެ.","",""],["₃ سورة آل عمران","4","مِن قَبۡلُ هُدٗى لِّلنَّاسِ وَأَنزَلَ ٱلۡفُرۡقَانَۗ إِنَّ ٱلَّذِينَ كَفَرُواْ بِـَٔايَٰتِ ٱللَّهِ لَهُمۡ عَذَابٞ شَدِيدٞۗ وَٱللَّهُ عَزِيزٞ ذُو ٱنتِقَامٍ ٤","من قبل هدى للناس وأنزل الفرقان إن الذين كفروا بآيات الله لهم عذاب شديد والله عزيز ذو انتقام","(އެއީ) ގުރްއާންގެ ކުރިންނެވެ. (އެއީ) މީސްތަކުންނަށްހުރި ހިދާޔަތެކެވެ. އަދި، އެކަލާނގެ، ހައްގާއި ބާތިލު ވަކިކުރަނިވި ފޮތް (އެބަހީ: ގުރްއާން) ބާވައިލެއްވިއެވެ. ހަމަކަށަވަރުން، ﷲގެ އާޔަތްތަކަށް ކާފިރުވި މީހުންނަށް ގަދަވެގެންވާ އަޒާބު ހުށްޓެވެ. ﷲއީ، ބަދަލު ހިއްޕެވުމުގެ ވެރި، ގަދަފަދަވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","5","إِنَّ ٱللَّهَ لَا يَخۡفَىٰ عَلَيۡهِ شَيۡءٞ فِي ٱلۡأَرۡضِ وَلَا فِي ٱلسَّمَآءِ ٥","إن الله لا يخفى عليه شيء في الأرض ولا في السماء","ހަމަކަށަވަރުން، ﷲއީ، ބިމާއި އުޑުގައިވާ އެއްވެސް އެއްޗެއް އެކަލާނގެއަށް ވަންހަނާވެގެންނުވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","6","هُوَ ٱلَّذِي يُصَوِّرُكُمۡ فِي ٱلۡأَرۡحَامِ كَيۡفَ يَشَآءُۚ لَآ إِلَٰهَ إِلَّا هُوَ ٱلۡعَزِيزُ ٱلۡحَكِيمُ ٦","هو الذي يصوركم في الأرحام كيف يشاء لا إله إلا هو العزيز الحكيم","އެކަލާނގެ އިރާދަކުރައްވާފަދަޔަކުން ރަޙިމު ތަކުގައި ތިޔަބައިމީހުން ޞޫރަކުރައްވަނީ އެކަލާނގެއެވެ. އެކަލާނގެ ފިޔަވައި (ހައްގު ވެގެން އަޅުކަމެއްވެވޭ) އިލާހަކު ނުވެތެވެ. (އެކަލާނގެއީ) ގަދަފަދަވަންތަ ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","7","هُوَ ٱلَّذِيٓ أَنزَلَ عَلَيۡكَ ٱلۡكِتَٰبَ مِنۡهُ ءَايَٰتٞ مُّحۡكَمَٰتٌ هُنَّ أُمُّ ٱلۡكِتَٰبِ وَأُخَرُ مُتَشَٰبِهَٰتٞۖ فَأَمَّا ٱلَّذِينَ فِي قُلُوبِهِمۡ زَيۡغٞ فَيَتَّبِعُونَ مَا تَشَٰبَهَ مِنۡهُ ٱبۡتِغَآءَ ٱلۡفِتۡنَةِ وَٱبۡتِغَآءَ تَأۡوِيلِهِۦۖ وَمَا يَعۡلَمُ تَأۡوِيلَهُۥٓ إِلَّا ٱللَّهُۗ وَٱلرَّـٰ‌سِخُونَ فِي ٱلۡعِلۡمِ يَقُولُونَ ءَامَنَّا بِهِۦ كُلّٞ مِّنۡ عِندِ رَبِّنَاۗ وَمَا يَذَّكَّرُ إِلَّآ أُوْلُواْ ٱلۡأَلۡبَٰبِ ٧","هو الذي أنزل عليك الكتاب منه آيات محكمات هن أم الكتاب وأخر متشابهات فأما الذين في قلوبهم زيغ فيتبعون ما تشابه منه ابتغاء الفتنة وابتغاء تأويله وما يعلم تأويله إلا الله والراسخون في العلم يقولون آمنا به كل من عند ربنا وما يذكر إلا أولو الألباب","އެކަލާނގެއީ، ކަލޭގެފާނުގެ މައްޗަށް ފޮތް ބާވައިލެއްވި ކަލާނގެއެވެ. އޮޅުމެއްނެތި، މާނަ ސާފުކޮށް އެނގޭ އާޔަތް ތަކެއް އޭގެތެރޭގައިވެއެވެ. އެ އާޔަތް ތަކަކީ، އެ ފޮތުގެ މައިގަނޑު ބަޔެވެ. އަދި متشابه އާޔަތް ތަކެއްވެސްވެއެވެ. (އެބަހީ: ﷲއަށް މެނުވީ އޭގެ މާނަ އެނގުންނުވާ، ނުވަތަ އިލްމީ ނަޡަރަކުން ބަލައިގެންމެނުވީ އޭގެ މާނަ ދޭހަނުވާ އާޔަތް ތަކެއްވެސް އޭގެތެރޭގައި ވެއެވެ.) ފަހެ، ހައްގު މަގުން އެއްކިބާވުމުގެގޮތް، އެއުރެންގެ ހިތްތަކުގައިވާ މީހުން ދަންނާށެވެ! ފަހެ، އެއުރެން ފިތުނަ އުފެއްދުމުގެ ބޭނުމުގައްޔާއި، އެ އާޔަތްތައް އެކިގޮތްގޮތަށް މާނަކުރުމުގެ ބޭނުމުގައި، އެ ފޮތުގެ ތެރޭގައި متشابه އާޔަތްތައް ނަގައި، އޭގައި ހިފަހައްޓަތެވެ. އެ އާޔަތްތަކުގެ ހަގީގީ މާނަ، ﷲއަށް މެނުވީ އެނގިގެނެއް ނުވެތެވެ. އިލްމުގައި ހަރުދަނާކަމާއި ޘާބިތު ކަން ލިބިފައިވާ މީހުން ބުނާހުށީ، ތިމަންމެން މިތިބީ އެ އާޔަތްތަކަށް އީމާން ވެގެންނެވެ. ހުރިހާ އާޔަތް ތަކެއްވެސްވަނީ، ތިމަންމެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުންނެވެ. ބުއްދީގެ އަހުލުވެރިން މެނުވީ ވިސްނައި ހަނދުމަކޮށެއް ނަހަދަތެވެ.","",""],["₃ سورة آل عمران","8","رَبَّنَا لَا تُزِغۡ قُلُوبَنَا بَعۡدَ إِذۡ هَدَيۡتَنَا وَهَبۡ لَنَا مِن لَّدُنكَ رَحۡمَةًۚ إِنَّكَ أَنتَ ٱلۡوَهَّابُ ٨","ربنا لا تزغ قلوبنا بعد إذ هديتنا وهب لنا من لدنك رحمة إنك أنت الوهاب","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެންނަށް ތެދުމަގު ދައްކަވައިފުމަށްފަހުގައި، އަޅަމެންގެ ހިތްތައް ހައްގުން އެއްކިބާ ނުކުރައްވާނދޭވެ! އަދި އަޅަމެންނަށް އިބަރަސްކަލާނގެ ހަޒުރަތުން ރަހުމަތެއް ދެއްވާނދޭވެ! ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ، ގިނަގުނަ ނިއުމަތްތައް ދެއްވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","9","رَبَّنَآ إِنَّكَ جَامِعُ ٱلنَّاسِ لِيَوۡمٖ لَّا رَيۡبَ فِيهِۚ إِنَّ ٱللَّهَ لَا يُخۡلِفُ ٱلۡمِيعَادَ ٩","ربنا إنك جامع الناس ليوم لا ريب فيه إن الله لا يخلف الميعاد","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ، އެދުވަހަކާމެދު ޝައްކެއްނެތް ދުވަހުގައި (ހިސާބު ބެއްލެވުމަށް) މީސްތަކުން އެއްކުރައްވާ ރަސްކަލާނގެއެވެ. ހަމަކަށަވަރުން، ﷲ، ވައުދާ ޚިލާފުވެ ވޮޑިއެއް ނުގަންނަވަތެވެ.","",""],["₃ سورة آل عمران","10","إِنَّ ٱلَّذِينَ كَفَرُواْ لَن تُغۡنِيَ عَنۡهُمۡ أَمۡوَٰلُهُمۡ وَلَآ أَوۡلَٰدُهُم مِّنَ ٱللَّهِ شَيۡـٔٗاۖ وَأُوْلَـٰٓئِكَ هُمۡ وَقُودُ ٱلنَّارِ ١٠","إن الذين كفروا لن تغني عنهم أموالهم ولا أولادهم من الله شيئا وأولئك هم وقود النار","ހަމަކަށަވަރުން، ކާފިރުވި މީހުންނަކީ އެއުރެންގެ މުދާތަކަކަށް އަދި އެއުރެންގެ ދަރިންނަކަށްވެސް، ﷲގެ ހަޒުރަތުން އެއުރެންނަށް އެއްވެސްކަމެއް ފުއްދައި ނުދެވޭނޭ ބަޔެކެވެ. އަދި، އެއުރެންނީ ހަމަ، ނަރަކައިގެ ދަރެވެ.","",""],["₃ سورة آل عمران","11","كَدَأۡبِ ءَالِ فِرۡعَوۡنَ وَٱلَّذِينَ مِن قَبۡلِهِمۡۚ كَذَّبُواْ بِـَٔايَٰتِنَا فَأَخَذَهُمُ ٱللَّهُ بِذُنُوبِهِمۡۗ وَٱللَّهُ شَدِيدُ ٱلۡعِقَابِ ١١","كدأب آل فرعون والذين من قبلهم كذبوا بآياتنا فأخذهم الله بذنوبهم والله شديد العقاب","(އެއުރެންގެ އާދަ ވީ) ފިރްޢައުނުގެ މީހުންނާއި، އަދި، އެއުރެންގެ ކުރިން އުޅުނު (ނުބައި) މީހުންގެ އާދަ ފަދައިންނެވެ. އެ އެންމެންވެސް ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުރިއެވެ. ދެން، އެއުރެންގެ ފާފަތަކުގެ ސަބަބުން، ﷲ، އެއުރެން ހަލާކު ކުރެއްވިއެވެ. ﷲއީ، އުގޫބާތް ގަދަފަދަވެގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","12","قُل لِّلَّذِينَ كَفَرُواْ سَتُغۡلَبُونَ وَتُحۡشَرُونَ إِلَىٰ جَهَنَّمَۖ وَبِئۡسَ ٱلۡمِهَادُ ١٢","قل للذين كفروا ستغلبون وتحشرون إلى جهنم وبئس المهاد","ކާފިރުވި މީހުންނަށް ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން (ދުނިޔޭގައި) ދެރަކޮށް، ބަލިކޮށްލައްވާހުށްޓެވެ. އަދި (އާޚިރަތުގައި) ތިޔަބައިމީހުން ނަރަކަޔަށް އެއްކުރައްވާހުށްޓެވެ. އަދި، އެ ތަންމަތީގެ ހުރި ނުބައިކަމާއެވެ!","",""],["₃ سورة آل عمران","13","قَدۡ كَانَ لَكُمۡ ءَايَةٞ فِي فِئَتَيۡنِ ٱلۡتَقَتَاۖ فِئَةٞ تُقَٰتِلُ فِي سَبِيلِ ٱللَّهِ وَأُخۡرَىٰ كَافِرَةٞ يَرَوۡنَهُم مِّثۡلَيۡهِمۡ رَأۡيَ ٱلۡعَيۡنِۚ وَٱللَّهُ يُؤَيِّدُ بِنَصۡرِهِۦ مَن يَشَآءُۚ إِنَّ فِي ذَٰلِكَ لَعِبۡرَةٗ لِّأُوْلِي ٱلۡأَبۡصَٰرِ ١٣","قد كان لكم آية في فئتين التقتا فئة تقاتل في سبيل الله وأخرى كافرة يرونهم مثليهم رأي العين والله يؤيد بنصره من يشاء إن في ذلك لعبرة لأولي الأبصار","(ބަދުރު ހަނގުރާމައިގެ ދުވަހުގައި) ބައްދަލުވި ދެބައިމީހުން (ގެ ކަންތަކު) ގައި، ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށް އިބްރަތެއްވެއެވެ. އެއްބަޔަކީ ﷲގެ މަގުގައި ހަނގުރާމަކުރާ ބަޔެކެވެ. އަނެއްބަޔަކީ ކާފިރު ބަޔެކެވެ. އެއުރެންނަށް ލޮލަށް ސާފުކޮށް ފެންނަގޮތުގައި، މުސްލިމުން ފެންނަނީ، އެއުރެންގެ ދެގުނަޔަށެވެ. ﷲ، އެކަލާނގެ ނަސްރުން ވާގިދެއްވަނީ، އެކަލާނގެ އިރާދަކުރައްވާ ބަޔަކަށެވެ. ހަމަކަށަވަރުން، އެކަމުގައި، ބުއްދީގެ އަހުލުވެރިންނަށް އިބްރަތެއްވާކަން ޔަގީނެވެ.","",""],["₃ سورة آل عمران","14","زُيِّنَ لِلنَّاسِ حُبُّ ٱلشَّهَوَٰتِ مِنَ ٱلنِّسَآءِ وَٱلۡبَنِينَ وَٱلۡقَنَٰطِيرِ ٱلۡمُقَنطَرَةِ مِنَ ٱلذَّهَبِ وَٱلۡفِضَّةِ وَٱلۡخَيۡلِ ٱلۡمُسَوَّمَةِ وَٱلۡأَنۡعَٰمِ وَٱلۡحَرۡثِۗ ذَٰلِكَ مَتَٰعُ ٱلۡحَيَوٰةِ ٱلدُّنۡيَاۖ وَٱللَّهُ عِندَهُۥ حُسۡنُ ٱلۡمَـَٔابِ ١٤","زين للناس حب الشهوات من النساء والبنين والقناطير المقنطرة من الذهب والفضة والخيل المسومة والأنعام والحرث ذلك متاع الحياة الدنيا والله عنده حسن المآب","އަންހެނުންނާއި، ދަރިންނާއި، ރަނާއި، ރިހީގެ ތެރެއިން އެއްކުރެވިފައިވާ ގިނަބައިވަރުތަކާއި، މޮޅު އަސްތަކާއި، ގެރިބަކަރި ޖަމަލާއި، ދަނޑުބިމާއި، މިތަކެއްޗަށް އެދުމުގެ ލޯބި، މީސްތަކުންނަށް ޒީނަތް ތެރި ކުރެއްވިއެވެ. އެއީ، ދުނިޔޭގެ ދިރިއުޅުމުގައި އުފާލިބިދޭ ތަކެއްޗެވެ. ނަމަވެސް އެނބުރިދަނިވި ރިވެތިވެގެންވާ ތަންވަނީ ﷲގެ ހަޒުރަތު ގައެވެ.","",""],["₃ سورة آل عمران","15","۞قُلۡ أَؤُنَبِّئُكُم بِخَيۡرٖ مِّن ذَٰلِكُمۡۖ لِلَّذِينَ ٱتَّقَوۡاْ عِندَ رَبِّهِمۡ جَنَّـٰتٞ تَجۡرِي مِن تَحۡتِهَا ٱلۡأَنۡهَٰرُ خَٰلِدِينَ فِيهَا وَأَزۡوَٰجٞ مُّطَهَّرَةٞ وَرِضۡوَٰنٞ مِّنَ ٱللَّهِۗ وَٱللَّهُ بَصِيرُۢ بِٱلۡعِبَادِ ١٥","قل أؤنبئكم بخير من ذلكم للذين اتقوا عند ربهم جنات تجري من تحتها الأنهار خالدين فيها وأزواج مطهرة ورضوان من الله والله بصير بالعباد","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެހުރިހައިތަކެއްޗަށްވުރެ ހެޔޮކަން ބޮޑުވެގެންވާ ކަމެއްގެ، ވާހަކަ ތިޔަބައިމީހުންގެ ގާތުގައި ތިމަންކަލޭގެފާނު ވިދާޅުވަންހެއްޔެވެ؟ (އެއީ) ތަގުވާވެރިވި މީހުންނަށް އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި، ސުވަރުގެތަކެއް ވެއެވެ. އެތާނގެދަށުން ފެންކޯރުތައް ހިނގަހިނގައިހުރެތެވެ. އެ ސުވަރުގެތަކުގައި، ދެމިތިބޭ ޙާލު ގަޔެވެ. އަދި، ތާހިރު ވެގެންވާ އަނބިންތަކެއްވެސް (އެއުރެންނަށް) ހުށްޓެވެ. އަދި، ﷲގެ ހަޒުރަތުން ރުއްސެވުން (އެއުރެންނަށް) ހުށްޓެވެ. ﷲއީ، އަޅުތަކުންގެ ކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","16","ٱلَّذِينَ يَقُولُونَ رَبَّنَآ إِنَّنَآ ءَامَنَّا فَٱغۡفِرۡ لَنَا ذُنُوبَنَا وَقِنَا عَذَابَ ٱلنَّارِ ١٦","الذين يقولون ربنا إننا آمنا فاغفر لنا ذنوبنا وقنا عذاب النار","އެއުރެންނީ ދަންނަވާ މީހުންނެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، އަޅަމެން އީމާން ވެއްޖައީމުއެވެ. ފަހެ، އަޅަމެންގެ ފާފަތައް، އަޅަމެންނަށް ފުއްސަވާނދޭވެ! އަދި، ނަރަކައިގެ އަޒާބުން އަޅަމެން ދިންނަވާނދޭވެ!","",""],["₃ سورة آل عمران","17","ٱلصَّـٰبِرِينَ وَٱلصَّـٰدِقِينَ وَٱلۡقَٰنِتِينَ وَٱلۡمُنفِقِينَ وَٱلۡمُسۡتَغۡفِرِينَ بِٱلۡأَسۡحَارِ ١٧","الصابرين والصادقين والقانتين والمنفقين والمستغفرين بالأسحار","(އެއުރެންނީ) ކެތްތެރިންނެވެ. އަދި، ތެދުވެރިންނެވެ. އަދި، ﷲއަށް ކިޔަމަންތެރިވާ މީހުންނެވެ. އަދި، (ހެޔޮގޮތުގައި) ހޭދަކުރާ މީހުންނެވެ. އަދި، ހާރުދަމުގައި ފާފަފުއްސެވުންއެދި ދުއާކުރާ މީހުންނެވެ.","",""],["₃ سورة آل عمران","18","شَهِدَ ٱللَّهُ أَنَّهُۥ لَآ إِلَٰهَ إِلَّا هُوَ وَٱلۡمَلَـٰٓئِكَةُ وَأُوْلُواْ ٱلۡعِلۡمِ قَآئِمَۢا بِٱلۡقِسۡطِۚ لَآ إِلَٰهَ إِلَّا هُوَ ٱلۡعَزِيزُ ٱلۡحَكِيمُ ١٨","شهد الله أنه لا إله إلا هو والملائكة وأولو العلم قائما بالقسط لا إله إلا هو العزيز الحكيم","ހަމަކަށަވަރުން، ﷲ، އެކަލާނގެ ފިޔަވައި (ހައްގު ވެގެން އަޅުކަމެއްވެވޭ) އިލާހަކު ނުވާކަމަށް ހެކިވެވޮޑިގެންފިއެވެ. އަދި، މަލާއިކަތްނާއި، އިލްމުގެ އަހުލުވެރިންވެސް (އެކަމަށް) ހެކިވިއެވެ. (އެކަލާނގެ ހެއްދެވި ތަކެތި ތަދްބީރުކުރެއްވުމުގައި) ޢަދުލުވެރި ކަމާއިގެން އެކަލާނގެ ގާއިމުވެ ވޮޑިގެންވެތެވެ. އެކަލާނގެ މެނުވީ (ހައްގު ވެގެން އަޅުކަމެއްވެވޭ) އިލާހަކު ނުވެތެވެ. (އެކަލާނގެއީ) ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","19","إِنَّ ٱلدِّينَ عِندَ ٱللَّهِ ٱلۡإِسۡلَٰمُۗ وَمَا ٱخۡتَلَفَ ٱلَّذِينَ أُوتُواْ ٱلۡكِتَٰبَ إِلَّا مِنۢ بَعۡدِ مَا جَآءَهُمُ ٱلۡعِلۡمُ بَغۡيَۢا بَيۡنَهُمۡۗ وَمَن يَكۡفُرۡ بِـَٔايَٰتِ ٱللَّهِ فَإِنَّ ٱللَّهَ سَرِيعُ ٱلۡحِسَابِ ١٩","إن الدين عند الله الإسلام وما اختلف الذين أوتوا الكتاب إلا من بعد ما جاءهم العلم بغيا بينهم ومن يكفر بآيات الله فإن الله سريع الحساب","ހަމަކަށަވަރުން، ﷲގެ ހަޒުރަތުގައި، ދީނަކީ، އިސްލާމް ދީނެވެ. އަދި، ފޮތް ލިބުނުމީހުން އެއުރެންނަށް (ހައްގު ގޮތް) އެނގުމަށްފަހުގައި މެނުވީ، އެއުރެން ޚިލާފު ވެއެއް ނުގަނެތެވެ. (އެއީ) އެއުރެންގެ މެދުގައިވާ ހަސަދަވެރިކަމުގެ ގޮތުންނެވެ. ﷲގެ އާޔަތްތަކަށް ކާފިރުވާ މީހުން (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ހިސާބު ބެއްލެވުން އަވަސްވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","20","فَإِنۡ حَآجُّوكَ فَقُلۡ أَسۡلَمۡتُ وَجۡهِيَ لِلَّهِ وَمَنِ ٱتَّبَعَنِۗ وَقُل لِّلَّذِينَ أُوتُواْ ٱلۡكِتَٰبَ وَٱلۡأُمِّيِّـۧنَ ءَأَسۡلَمۡتُمۡۚ فَإِنۡ أَسۡلَمُواْ فَقَدِ ٱهۡتَدَواْۖ وَّإِن تَوَلَّوۡاْ فَإِنَّمَا عَلَيۡكَ ٱلۡبَلَٰغُۗ وَٱللَّهُ بَصِيرُۢ بِٱلۡعِبَادِ ٢٠","فإن حاجوك فقل أسلمت وجهي لله ومن اتبعن وقل للذين أوتوا الكتاب والأميين أأسلمتم فإن أسلموا فقد اهتدوا وإن تولوا فإنما عليك البلاغ والله بصير بالعباد","ފަހެ، އެއުރެން ކަލޭގެފާނާ ޖަދަލުކޮށްފިނަމަ، ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނުގެ މޫނުފުޅު (އެބަހީ: ފުރާނަޔާއި ހަށިކޮޅު) ﷲއަށް ޚާލިސް ކޮށް ކިޔަމަންކުރައްވައިފީމެވެ. އަދި، ތިމަންކަލޭގެފާނަށް ތަބާވި މީހުންވެސްމެއެވެ. ފޮތް ލިބުނު މީހުންނާއި، އުއްމީންނަށް (އެބަހީ: އަރަބީންގެ މުޝްރިކުންނަށް) ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ކިޔަމަންވެއްޖައީމުހެއްޔެވެ؟ ފަހެ، އެއުރެން ކިޔަމަން ވެއްޖެނަމަ، އެއުރެން ތެދުމަގު ލިބިގެންފިކަން ކަށަވަރެވެ. އަދި، އެއުރެން އެނބުރި ފުރަގަސްދީފިނަމަ، ކަލޭގެފާނަށް އޮތްކަން ކަށަވަރީ، (ބާވައިލެއްވި ކަންތައް) އިއްވެވުމެވެ. ﷲއީ، އަޅުތަކުންގެ ކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","21","إِنَّ ٱلَّذِينَ يَكۡفُرُونَ بِـَٔايَٰتِ ٱللَّهِ وَيَقۡتُلُونَ ٱلنَّبِيِّـۧنَ بِغَيۡرِ حَقّٖ وَيَقۡتُلُونَ ٱلَّذِينَ يَأۡمُرُونَ بِٱلۡقِسۡطِ مِنَ ٱلنَّاسِ فَبَشِّرۡهُم بِعَذَابٍ أَلِيمٍ ٢١","إن الذين يكفرون بآيات الله ويقتلون النبيين بغير حق ويقتلون الذين يأمرون بالقسط من الناس فبشرهم بعذاب أليم","ހަމަކަށަވަރުން، ﷲގެ އާޔަތްތަކަށް ކާފިރުވެ، ހައްގަކާނުލައި، ނަބިއްޔުން ގަތުލު ކޮށް، މީސްތަކުންގެ ތެރެއިން ޢަދުލަށް އަމުރުކުރާ މީހުން ގަތުލު ކޮށް އުޅޭމީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެންނަށް ވޭންދެނިވި އަޒާބު ހުރިކަމުގެ ޚަބަރު، ކަލޭގެފާނު ދެއްވާށެވެ!","",""],["₃ سورة آل عمران","22","أُوْلَـٰٓئِكَ ٱلَّذِينَ حَبِطَتۡ أَعۡمَٰلُهُمۡ فِي ٱلدُّنۡيَا وَٱلۡأٓخِرَةِ وَمَا لَهُم مِّن نَّـٰصِرِينَ ٢٢","أولئك الذين حبطت أعمالهم في الدنيا والآخرة وما لهم من ناصرين","އެއުރެންނީ، ދުނިޔެއާއި، އާޚިރަތުގައި، އެއުރެންގެ ޢަމަލުތައް ބާތިލު ވެފައިވާ މީހުންނެވެ. އަދި، އެއުރެންނަށް ނަސްރު ދޭނެ އެއްވެސްބަޔަކު ނުވެތެވެ.","",""],["₃ سورة آل عمران","23","أَلَمۡ تَرَ إِلَى ٱلَّذِينَ أُوتُواْ نَصِيبٗا مِّنَ ٱلۡكِتَٰبِ يُدۡعَوۡنَ إِلَىٰ كِتَٰبِ ٱللَّهِ لِيَحۡكُمَ بَيۡنَهُمۡ ثُمَّ يَتَوَلَّىٰ فَرِيقٞ مِّنۡهُمۡ وَهُم مُّعۡرِضُونَ ٢٣","ألم تر إلى الذين أوتوا نصيبا من الكتاب يدعون إلى كتاب الله ليحكم بينهم ثم يتولى فريق منهم وهم معرضون","ފޮތުގެ ތެރެއިން ބައެއް (އެއުރެންނަށް) ލިބުނު މީހުން އެއުރެންގެ މެދުގައި، ﷲގެ ފޮތުގައިވާގޮތަށް، ހުކުމްކުރުމަށް ގޮވާލީމާ، ދެން އޭގެތެރެއިން ބަޔަކު، ދެކޮޅުވެރިވެ، ފުރަގަސްދީ ދާތަން، ކަލޭގެފާނު ދެކެވަޑައިނުގަންނަވަމުތޯއެވެ؟","",""],["₃ سورة آل عمران","24","ذَٰلِكَ بِأَنَّهُمۡ قَالُواْ لَن تَمَسَّنَا ٱلنَّارُ إِلَّآ أَيَّامٗا مَّعۡدُودَٰتٖۖ وَغَرَّهُمۡ فِي دِينِهِم مَّا كَانُواْ يَفۡتَرُونَ ٢٤","ذلك بأنهم قالوا لن تمسنا النار إلا أياما معدودات وغرهم في دينهم ما كانوا يفترون","އެއީ ގުނާލެވިގެންވާ ކުޑަދުވަސްކޮޅަކު މެނުވީ، ތިމަންމެންގައި ނަރަކައިގެ އަލިފާން ނުބީހޭނެޔޭ އެއުރެން ބުނެ އުޅުނުކަމުގެ ސަބަބުންނެވެ. އަދި އެއުރެން ދޮގުން އުފައްދާފައިވާ ބަސްތައް އެއުރެންގެ ދީނާ މެދުގައި އެއުރެން ހެއްލުންތެރި ކުޅައެވެ.","",""],["₃ سورة آل عمران","25","فَكَيۡفَ إِذَا جَمَعۡنَٰهُمۡ لِيَوۡمٖ لَّا رَيۡبَ فِيهِ وَوُفِّيَتۡ كُلُّ نَفۡسٖ مَّا كَسَبَتۡ وَهُمۡ لَا يُظۡلَمُونَ ٢٥","فكيف إذا جمعناهم ليوم لا ريب فيه ووفيت كل نفس ما كسبت وهم لا يظلمون","ފަހެ، އެދުވަހާމެދު ޝައްކުކަމެއްނެތް ދުވަހަކުން (އެބަހީ: ގިޔާމަތް ދުވަހުން) ތިމަންރަސްކަލާނގެ އެއުރެން އެއްކުރައްވައި އެއުރެންނަށް ބޭއިންސާފު ނުކުރައްވާގޮތުގައި، ކޮންމެ ނަފްސަކަށްމެ އެ ނަފްސެއް ހޯދިކަމެއް (ގެ ޖަޒާ) ފުރިހަމަޔަށް ލިބޭހިނދު، އެއުރެން (ގެ ޙާލު) ވާނީ ކޮންފަދަޔަކުން ހެއްޔެވެ؟","",""],["₃ سورة آل عمران","26","قُلِ ٱللَّهُمَّ مَٰلِكَ ٱلۡمُلۡكِ تُؤۡتِي ٱلۡمُلۡكَ مَن تَشَآءُ وَتَنزِعُ ٱلۡمُلۡكَ مِمَّن تَشَآءُ وَتُعِزُّ مَن تَشَآءُ وَتُذِلُّ مَن تَشَآءُۖ بِيَدِكَ ٱلۡخَيۡرُۖ إِنَّكَ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٞ ٢٦","قل اللهم مالك الملك تؤتي الملك من تشاء وتنزع الملك ممن تشاء وتعز من تشاء وتذل من تشاء بيدك الخير إنك على كل شيء قدير","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ވެރިކަން މިލްކުވެގެންވާ، ހައްދަވާ ބޮޑުކުރެއްވި ރަސްކަލާކޯއެވެ! އިބަރަސްކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ވެރިކަން ދެއްވަމުއެވެ. އަދި، އިބަރަސްކަލާނގެ އިރާދަކުރައްވާ މީހެއްގެ ކިބައިން ވެރިކަން ވަކިކުރައްވަމުއެވެ. އަދި، އިބަރަސްކަލާނގެ އިރާދަކުރައްވާ މީހަކު މަތިވެރިކުރައްވަމުއެވެ. އަދި، އިބަރަސްކަލާނގެ އިރާދަކުރައްވާ މީހަކު ނިކަމެތިކުރައްވަމުއެވެ. އެންމެހާ ހެޔޮކަންވަނީ، އިބަރަސްކަލާނގެ އަތްޕުޅުގައެވެ. ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ، ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","27","تُولِجُ ٱلَّيۡلَ فِي ٱلنَّهَارِ وَتُولِجُ ٱلنَّهَارَ فِي ٱلَّيۡلِۖ وَتُخۡرِجُ ٱلۡحَيَّ مِنَ ٱلۡمَيِّتِ وَتُخۡرِجُ ٱلۡمَيِّتَ مِنَ ٱلۡحَيِّۖ وَتَرۡزُقُ مَن تَشَآءُ بِغَيۡرِ حِسَابٖ ٢٧","تولج الليل في النهار وتولج النهار في الليل وتخرج الحي من الميت وتخرج الميت من الحي وترزق من تشاء بغير حساب","އިބަރަސްކަލާނގެ، ދުވާލުގެ ތެރެއަށް ރޭގަނޑު ވައްދަވަމުއެވެ. އަދި، ރޭގަނޑުގެ ތެރެއަށް ދުވާލު ވައްދަވަމުއެވެ. އަދި، މަރުވެފައިވާ ތަކެތީން ދިރޭތަކެތި ނެރުއްވަމުއެވެ. އަދި، ދިރޭތަކެތީން މަރުވެފައިވާ ތަކެތި ނެރުއްވަމުއެވެ. އަދި، އިބަރަސްކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ހިސާބެއްނެތި ރިޒްގު ދެއްވަމުއެވެ.","",""],["₃ سورة آل عمران","28","لَّا يَتَّخِذِ ٱلۡمُؤۡمِنُونَ ٱلۡكَٰفِرِينَ أَوۡلِيَآءَ مِن دُونِ ٱلۡمُؤۡمِنِينَۖ وَمَن يَفۡعَلۡ ذَٰلِكَ فَلَيۡسَ مِنَ ٱللَّهِ فِي شَيۡءٍ إِلَّآ أَن تَتَّقُواْ مِنۡهُمۡ تُقَىٰةٗۗ وَيُحَذِّرُكُمُ ٱللَّهُ نَفۡسَهُۥۗ وَإِلَى ٱللَّهِ ٱلۡمَصِيرُ ٢٨","لا يتخذ المؤمنون الكافرين أولياء من دون المؤمنين ومن يفعل ذلك فليس من الله في شيء إلا أن تتقوا منهم تقاة ويحذركم الله نفسه وإلى الله المصير","މުއުމިނުން، މުއުމިނުން ފިޔަވައި ކާފިރުން އެއީ، އެހީތެރިންކަމުގައި ނުހަދާހުށިކަމެވެ! އެކަންތައް (އެގޮތަށް) ކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، ﷲގެ ވާގިވެރިކަމުގެ ތެރެއިން އެއްވެސްކަމެއްގައި އެމީހަކު ނުވެތެވެ. އެއުރެންގެ ކިބައިން އަންނަ ނުރައްކަލަކުން ތިޔަބައިމީހުން ސަލާމަތްވުން މަޖުބޫރު ވެއްޖެ ޙާލެއްގައި މެނުވީއެވެ. އަދި، ﷲ އެކަލާނގެ ޢިގާބަށް ތިޔަބައިމީހުން ބިރުވެތި ކުރައްވަތެވެ. އެނބުރި ދިޔުންވަނީ ﷲގެ ހަޒުރަތަށެވެ.","",""],["₃ سورة آل عمران","29","قُلۡ إِن تُخۡفُواْ مَا فِي صُدُورِكُمۡ أَوۡ تُبۡدُوهُ يَعۡلَمۡهُ ٱللَّهُۗ وَيَعۡلَمُ مَا فِي ٱلسَّمَٰوَٰتِ وَمَا فِي ٱلۡأَرۡضِۗ وَٱللَّهُ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٞ ٢٩","قل إن تخفوا ما في صدوركم أو تبدوه يعلمه الله ويعلم ما في السماوات وما في الأرض والله على كل شيء قدير","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންގެ ހިތްތަކުގައިވާކަމެއް، ތިޔަބައިމީހުން ވަންހަނާކުޅަޔަސް، ނުވަތަ އެކަމެއް ތިޔަބައިމީހުން ފާޅުކުޅަޔަސް، ﷲ، އެކަމެއް ދެނެވޮޑިގެންވެތެވެ. އަދި، އުޑުތަކުގައި ވާހާ ކަމަކާއި، ބިމުގައި ވާހާ ކަމެއްވެސް، އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. ﷲއީ، ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","30","يَوۡمَ تَجِدُ كُلُّ نَفۡسٖ مَّا عَمِلَتۡ مِنۡ خَيۡرٖ مُّحۡضَرٗا وَمَا عَمِلَتۡ مِن سُوٓءٖ تَوَدُّ لَوۡ أَنَّ بَيۡنَهَا وَبَيۡنَهُۥٓ أَمَدَۢا بَعِيدٗاۗ وَيُحَذِّرُكُمُ ٱللَّهُ نَفۡسَهُۥۗ وَٱللَّهُ رَءُوفُۢ بِٱلۡعِبَادِ ٣٠","يوم تجد كل نفس ما عملت من خير محضرا وما عملت من سوء تود لو أن بينها وبينه أمدا بعيدا ويحذركم الله نفسه والله رءوف بالعباد","ކޮންމެ ނަފްސެއްމެ، ހެޔޮކަމުގެ ތެރެއިން، އެ ނަފްސެއް ކުޅަކަމަކާއި، ނުބައިކަމުގެ ތެރެއިން، އެ ނަފްސެއް ކުޅަކަމެއް ޙާޒިރުުކުރައްވާފައިވާތީ ދެކޭނޭ ދުވަސް (ހަނދުމަކުރާށެވެ! އެދުވަހުން) އެ ނަފްސެއް ކުޅަ ނުބައިކަމަކާއި، އެ ނަފްސަކާ ދެމެދު އެތަކެއް ދުރުމިނެއް ހުންނާނެނަމައޭ ހީކޮށް އެކަމަށް އެދޭނެތެވެ. ﷲ، އެކަލާނގެ ޢިގާބަށް ތިޔަބައިމީހުން ބިރުވެރިތިކުރައްވަތެވެ. ﷲއީ، އަޅުތަކުންނަށް ނުހަނު އޯގާވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","31","قُلۡ إِن كُنتُمۡ تُحِبُّونَ ٱللَّهَ فَٱتَّبِعُونِي يُحۡبِبۡكُمُ ٱللَّهُ وَيَغۡفِرۡ لَكُمۡ ذُنُوبَكُمۡۚ وَٱللَّهُ غَفُورٞ رَّحِيمٞ ٣١","قل إن كنتم تحبون الله فاتبعوني يحببكم الله ويغفر لكم ذنوبكم والله غفور رحيم","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން، ﷲއަށް ލޯބިވާކަމުގައި ވަނީނަމަ، ފަހެ، ތިޔަބައިމީހުން، ތިމަންކަލޭގެފާނަށް ތަބާ ވާށެވެ! އޭރުން، ﷲ، ތިޔަބައިމީހުންދެކެ ލޯބިވެވޮޑިގެންވާނެތެވެ. އަދި، ތިޔަބައިމީހުންނަށްޓަކައި، ތިޔަބައިމީހުންގެ ފާފަތައް ފުއްސަވައިދެއްވާނެތެވެ. ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","32","قُلۡ أَطِيعُواْ ٱللَّهَ وَٱلرَّسُولَۖ فَإِن تَوَلَّوۡاْ فَإِنَّ ٱللَّهَ لَا يُحِبُّ ٱلۡكَٰفِرِينَ ٣٢","قل أطيعوا الله والرسول فإن تولوا فإن الله لا يحب الكافرين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން، ﷲއަށާއި، ރަސޫލާއަށް ކިޔަމަންވާށެވެ! ފަހެ، ތިޔަބައިމީހުން އެނބުރި ފުރަގަސްދީފިނަމަ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ކާފިރު ންދެކެ ﷲ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["₃ سورة آل عمران","33","۞إِنَّ ٱللَّهَ ٱصۡطَفَىٰٓ ءَادَمَ وَنُوحٗا وَءَالَ إِبۡرَٰهِيمَ وَءَالَ عِمۡرَٰنَ عَلَى ٱلۡعَٰلَمِينَ ٣٣","إن الله اصطفى آدم ونوحا وآل إبراهيم وآل عمران على العالمين","ހަމަކަށަވަރުން، ﷲ، އާދަމުގެފާނާއި، ނޫޙުގެފާނާއި، އިބްރާހީމްގެފާނުގެ އާލުވެރިންނާއި، ޢިމްރާންގެ އާލުވެރިން (އެދުވަސްވަރުގެ) އާލަމްތަކުގެ މައްޗަށް ޚިޔާރުކުރެއްވިއެވެ.","",""],["₃ سورة آل عمران","34","ذُرِّيَّةَۢ بَعۡضُهَا مِنۢ بَعۡضٖۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ ٣٤","ذرية بعضها من بعض والله سميع عليم","އޭގެތެރެއިން އެއްބަޔަކީ، އަނެއްބަޔެއްގެ ކިބައިން އައިސްފައިވާ ދަރިފަސްކޮޅެކެވެ. ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","35","إِذۡ قَالَتِ ٱمۡرَأَتُ عِمۡرَٰنَ رَبِّ إِنِّي نَذَرۡتُ لَكَ مَا فِي بَطۡنِي مُحَرَّرٗا فَتَقَبَّلۡ مِنِّيٓۖ إِنَّكَ أَنتَ ٱلسَّمِيعُ ٱلۡعَلِيمُ ٣٥","إذ قالت امرأت عمران رب إني نذرت لك ما في بطني محررا فتقبل مني إنك أنت السميع العليم","ޢިމްރާންގެ އަނބިކަނބަލުން ވިދާޅުވިހިނދު، ހަނދުމަކުރާށެވެ! އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! އަޅުގެ ބަނޑުގައި އޮތް ދަރި (ބައިތުލް މަގްދިސްގެ ޚިދުމަތަށްޓަކައި، އެހެން ހުރިހާކަމަކުން) މިނިވަންކޮށް، އިބަރަސްކަލާނގެ ހަޒުރަތަށް ޚާލިސްކުރުމަށް، ހަމަކަށަވަރުން، ނަދުރުގެންފީމެވެ. ފަހެ، އަޅުގެ ކިބައިން (އެކަން) ގަބޫލުކުރައްވާނދޭވެ! ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","36","فَلَمَّا وَضَعَتۡهَا قَالَتۡ رَبِّ إِنِّي وَضَعۡتُهَآ أُنثَىٰ وَٱللَّهُ أَعۡلَمُ بِمَا وَضَعَتۡ وَلَيۡسَ ٱلذَّكَرُ كَٱلۡأُنثَىٰۖ وَإِنِّي سَمَّيۡتُهَا مَرۡيَمَ وَإِنِّيٓ أُعِيذُهَا بِكَ وَذُرِّيَّتَهَا مِنَ ٱلشَّيۡطَٰنِ ٱلرَّجِيمِ ٣٦","فلما وضعتها قالت رب إني وضعتها أنثى والله أعلم بما وضعت وليس الذكر كالأنثى وإني سميتها مريم وإني أعيذها بك وذريتها من الشيطان الرجيم","ދެން، އެކަމަނާ، އެ ދަރިކަނބަލުންނާއިގެން ރައްކާވިހިނދު، ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! ހަމަކަށަވަރުން، އަޅު ވިހޭ ދަރިޔަކީ، އަންހެން ކުއްޖެކެވެ. އެކަމަނާ ރައްކާވީ، ކޮންކަހަލަ ކުއްޖެއްކަން ﷲ ދެނެވޮޑިގެންވެތެވެ. (އެކަމަނާ ދެންނެވިއެވެ.) ފިރިހެންކުއްޖަކު އަންހެންކުއްޖަކާ އެއްފަދައެއްނޫނެވެ. އަދި، ހަމަކަށަވަރުން، އެ ދަރިކަނބަލުންނަށް މަރިޔަމް އޭ ނަންދީފީމެވެ. އަދި، ހަމަކަށަވަރުން، ރަހުމަތުން ބޭރުކުރައްވާފައިވާ ޝައިތާނާގެ ކިބައިން، އެ ދަރިކަނބަލުންނާއި، އެ ދަރިކަނބަލުންގެ ދަރިފަސްކޮޅު، ރައްކާތެރިކޮށްދެއްވުމަށްއެދި، އިބަރަސްކަލާނގެ ހަޒުރަތަށް ދަންނަވަމެވެ.","",""],["₃ سورة آل عمران","37","فَتَقَبَّلَهَا رَبُّهَا بِقَبُولٍ حَسَنٖ وَأَنۢبَتَهَا نَبَاتًا حَسَنٗا وَكَفَّلَهَا زَكَرِيَّاۖ كُلَّمَا دَخَلَ عَلَيۡهَا زَكَرِيَّا ٱلۡمِحۡرَابَ وَجَدَ عِندَهَا رِزۡقٗاۖ قَالَ يَٰمَرۡيَمُ أَنَّىٰ لَكِ هَٰذَاۖ قَالَتۡ هُوَ مِنۡ عِندِ ٱللَّهِۖ إِنَّ ٱللَّهَ يَرۡزُقُ مَن يَشَآءُ بِغَيۡرِ حِسَابٍ ٣٧","فتقبلها ربها بقبول حسن وأنبتها نباتا حسنا وكفلها زكريا كلما دخل عليها زكريا المحراب وجد عندها رزقا قال يا مريم أنى لك هذا قالت هو من عند الله إن الله يرزق من يشاء بغير حساب","ފަހެ، އެކަމަނާގެ ވެރިރަސްކަލާނގެ ރިވެތިވެގެންވާ ގަބޫލަކުން އެކަމަނާ ގަބޫލުކުރައްވައިފިއެވެ. އަދި، ރިވެތިވެގެންވާ ބޮޑުކުރެއްވުމަކުން އެކަމަނާ ބޮޑުކުރެއްވިއެވެ. އަދި، ޒަކަރިއްޔާގެފާނާ، އެކަމަނާ ބެލެހެއްޓެވުން ޙަވާލުކުރެއްވިއެވެ. އެކަމަނާގެ އަރިހަށް މިޙުރާބުގެ ތެރެޔަށް ޒަކަރިއްޔާގެފާނު، ވެދެވަޑައިގަންނަވާ ކޮންމެފަހަރަކު، އެކަމަނާގެ އަރިހުގައި، ކާތަކެތިވާތީ، އެކަލޭގެފާނު ދެކެވަޑައިގެން ވިދާޅުވެތެވެ. އޭ މަރިޔަމެވެ! ކަމަނާއަށް މިތަކެތި ލިބިވަޑައިގަންނަވަނީ ކޮންތާކުންތޯއެވެ؟ އެކަމަނާ ވިދާޅުވެތެވެ. އެއީ، ﷲގެ ހަޒުރަތުންނެވެ. ހަމަކަށަވަރުން، ﷲ އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް އެއްވެސް ހިސާބެއްނެތި ރިޒްގު ދެއްވަތެވެ.","",""],["₃ سورة آل عمران","38","هُنَالِكَ دَعَا زَكَرِيَّا رَبَّهُۥۖ قَالَ رَبِّ هَبۡ لِي مِن لَّدُنكَ ذُرِّيَّةٗ طَيِّبَةًۖ إِنَّكَ سَمِيعُ ٱلدُّعَآءِ ٣٨","هنالك دعا زكريا ربه قال رب هب لي من لدنك ذرية طيبة إنك سميع الدعاء","އެތާނގައި، ޒަކަރިއްޔާގެފާނު އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ދުއާކުރައްވައި ދެންނެވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! އިބަރަސްކަލާނގެ ހަޒުރަތުން، ހެޔޮލަފާ ރަނގަޅު ދަރިފަސްކޮޅެއް މިއަޅާއަށް ދެއްވާނދޭވެ! ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ، ގިނަގިނައިން ދުއާ އައްސަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","39","فَنَادَتۡهُ ٱلۡمَلَـٰٓئِكَةُ وَهُوَ قَآئِمٞ يُصَلِّي فِي ٱلۡمِحۡرَابِ أَنَّ ٱللَّهَ يُبَشِّرُكَ بِيَحۡيَىٰ مُصَدِّقَۢا بِكَلِمَةٖ مِّنَ ٱللَّهِ وَسَيِّدٗا وَحَصُورٗا وَنَبِيّٗا مِّنَ ٱلصَّـٰلِحِينَ ٣٩","فنادته الملائكة وهو قائم يصلي في المحراب أن الله يبشرك بيحيى مصدقا بكلمة من الله وسيدا وحصورا ونبيا من الصالحين","ދެންފަހެ، އެކަލޭގެފާނު މިޙުރާބުގައި ނަމާދު ކުރެއްވުމުގައި ގާއިމު ވެވަޑައިގެން ހުންނަވަނިކޮށް، އެކަލޭގެފާނަށް، މަލާއިކަތުން ގޮވާލައްވައި ދެންނެވިއެވެ. ހަމަކަށަވަރުން، ﷲ، ކަލޭގެފާނަށް ޔަޙްޔާގެފާނު ދެއްވާނެކަމުގެ އުފާވެރި ޚަބަރު ދެއްވަތެވެ. ﷲގެ ހަޒުރަތު ންވާ ކަލިމަ ފުޅެއް ތެދުކުރައްވާ ބޭކަލެއްގެ ގޮތުގައެވެ. އަދި، (އެކަލޭގެފާނު ވާހުށީ) މާތް ސާހިބެއްކަމަށާއި، އަންހެނުންނާ ދުރުހެލިވެ ރައްކާތެރިވެވަޑައިގެންވާ ބޭކަލެއްކަމަށާއި، ސާލިހުންގެ ތެރެއިންވާ ނަބީބޭކަލެއްކަމަށެވެ.","",""],["₃ سورة آل عمران","40","قَالَ رَبِّ أَنَّىٰ يَكُونُ لِي غُلَٰمٞ وَقَدۡ بَلَغَنِيَ ٱلۡكِبَرُ وَٱمۡرَأَتِي عَاقِرٞۖ قَالَ كَذَٰلِكَ ٱللَّهُ يَفۡعَلُ مَا يَشَآءُ ٤٠","قال رب أنى يكون لي غلام وقد بلغني الكبر وامرأتي عاقر قال كذلك الله يفعل ما يشاء","އެކަލޭގެފާނު ދެންނެވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! މިއަޅާޔަށް ދަރިޔަކު ލިބޭހުށީ ކޮންފަދަޔަކުންތޯއެވެ؟ ހަމަކަށަވަރުން، މިއަޅާވަނީ އުމުރުން ދުވަސްވެ މުސްކުޅިވެފައެވެ. އަދި، މިއަޅާގެ އަންހެނުންނަކީ، ދަރިޔަކު ލިބޭފަދަ މީހެއްނޫނެވެ. އެކަލާނގެ ވަހީކުރެއްވިއެވެ. (ކަންހުރީ) އެފަދައިންނެވެ. ﷲ، އެކަލާނގެ އިރާދަކުރައްވާކަމެއް ކުރައްވަތެވެ.","",""],["₃ سورة آل عمران","41","قَالَ رَبِّ ٱجۡعَل لِّيٓ ءَايَةٗۖ قَالَ ءَايَتُكَ أَلَّا تُكَلِّمَ ٱلنَّاسَ ثَلَٰثَةَ أَيَّامٍ إِلَّا رَمۡزٗاۗ وَٱذۡكُر رَّبَّكَ كَثِيرٗا وَسَبِّحۡ بِٱلۡعَشِيِّ وَٱلۡإِبۡكَٰرِ ٤١","قال رب اجعل لي آية قال آيتك ألا تكلم الناس ثلاثة أيام إلا رمزا واذكر ربك كثيرا وسبح بالعشي والإبكار","އެކަލޭގެފާނު ދެންނެވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! (އެކަމަށް އިޝާރަތްކުރާ) އަލާމަތެއް މިއަޅާޔަށް ލައްވާނދޭވެ! އެކަލާނގެ ވަހީކުރެއްވިއެވެ. (އެކަމުގައި) ކަލޭގެފާނުގެ އަލާމަތަކީ، ތިންދުވަސްވާންދެން، ކަލޭގެފާނަށް އިޝާރަތުން މެނުވީ މީހުންނާ ވާހަކަ ނުދެއްކެވި ހުންނެވުމެވެ. އަދި، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ގިނަގިނައިން ހަނދުމަކުރައްވާށެވެ! އަދި، ހަވީރާއި ހެނދުނު، ތަސްބީހަ ވިދާޅުވާށެވެ!","",""],["₃ سورة آل عمران","42","وَإِذۡ قَالَتِ ٱلۡمَلَـٰٓئِكَةُ يَٰمَرۡيَمُ إِنَّ ٱللَّهَ ٱصۡطَفَىٰكِ وَطَهَّرَكِ وَٱصۡطَفَىٰكِ عَلَىٰ نِسَآءِ ٱلۡعَٰلَمِينَ ٤٢","وإذ قالت الملائكة يا مريم إن الله اصطفاك وطهرك واصطفاك على نساء العالمين","މަލާއިކަތުން ވިދާޅުވިހިނދު، ހަނދުމަކުރައްވާށެވެ! އޭ މަރިޔަމްގެފާނެވެ! ހަމަކަށަވަރުން، ﷲ، ކަމަނާ ޚިޔާރުކުރައްވައި، ތާހިރުކުރައްވައި، (ކަމަނާގެ ދުވަސްވަރުގެ) އާލަމްތަކުގެ އަންހެނުންގެ މައްޗަށް، މާތްކުރައްވައި މަތިވެރި ކުރައްވައިފިއެވެ.","",""],["₃ سورة آل عمران","43","يَٰمَرۡيَمُ ٱقۡنُتِي لِرَبِّكِ وَٱسۡجُدِي وَٱرۡكَعِي مَعَ ٱلرَّـٰ‌كِعِينَ ٤٣","يا مريم اقنتي لربك واسجدي واركعي مع الراكعين","އޭ މަރިޔަމްގެފާނެވެ! ކަމަނާގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް، އަޅުކަން ޚާލިސްކުރައްވައި، ކިޔަމަންތެރިކަމުގައި ދެމިހުންނަވާށެވެ! އަދި، ސަޖިދަކުރައްވައި، އަދި، ރުކޫއުކުރާ މީހުންނާ އެކުގައި، ރުކޫއުކުރައްވާށެވެ!","",""],["₃ سورة آل عمران","44","ذَٰلِكَ مِنۡ أَنۢبَآءِ ٱلۡغَيۡبِ نُوحِيهِ إِلَيۡكَۚ وَمَا كُنتَ لَدَيۡهِمۡ إِذۡ يُلۡقُونَ أَقۡلَٰمَهُمۡ أَيُّهُمۡ يَكۡفُلُ مَرۡيَمَ وَمَا كُنتَ لَدَيۡهِمۡ إِذۡ يَخۡتَصِمُونَ ٤٤","ذلك من أنباء الغيب نوحيه إليك وما كنت لديهم إذ يلقون أقلامهم أيهم يكفل مريم وما كنت لديهم إذ يختصمون","އެއީ، ޣައިބުގެ ޚަބަރުތަކުގެ ތެރެއިން، ކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ ވަހީކުރައްވާ ޚަބަރު ތަކެވެ. މަރިޔަމްގެފާނު ބެލުމާ ޙަވާލު ވާނީ، އެއުރެންގެ ތެރެއިން ކާކުތޯ ބެލުމަށްޓަކައި (ގުރުޢަތު ލުމުގެ ގޮތުން) އެއުރެންގެ ގަލަމްތައް އުކި ހިނދު، އެއުރެންގެ ގާތުގައި ކަލޭގެފާނު ވަޑައިގެން ނުވަމުއެވެ. އަދި، އެއުރެން (އެކަމުގައި) ދެބަސްވެ ޚިލާފު ވީ ހިނދުގައިވެސް، އެއުރެންގެ ގާތުގައި ކަލޭގެފާނު ވަޑައިގެން ނުވަމުއެވެ.","",""],["₃ سورة آل عمران","45","إِذۡ قَالَتِ ٱلۡمَلَـٰٓئِكَةُ يَٰمَرۡيَمُ إِنَّ ٱللَّهَ يُبَشِّرُكِ بِكَلِمَةٖ مِّنۡهُ ٱسۡمُهُ ٱلۡمَسِيحُ عِيسَى ٱبۡنُ مَرۡيَمَ وَجِيهٗا فِي ٱلدُّنۡيَا وَٱلۡأٓخِرَةِ وَمِنَ ٱلۡمُقَرَّبِينَ ٤٥","إذ قالت الملائكة يا مريم إن الله يبشرك بكلمة منه اسمه المسيح عيسى ابن مريم وجيها في الدنيا والآخرة ومن المقربين","މަލާއިކަތުން ވިދާޅުވިހިނދު ހަނދުމަކުރައްވާށެވެ! އޭ މަރިޔަމްގެފާނެވެ! ހަމަކަށަވަރުން، ﷲ، އެކަލާނގެ ހަޒުރަތު ންވާ ކަލިމަ ފުޅެއްގެ ޚަބަރުން ކަމަނާޔަށް އުފާވެރި ޚަބަރު ދެއްވަތެވެ. (އެބަހީ: ޢީސާގެފާނު ލިބިވަޑައިގަންނަވާނޭ ކަމުގެ ބިޝާރާތް ދެއްވަތެވެ.) އެ ދަރިކަލުންގެ ނަންފުޅަކީ އަލްމަސީޙު ޢީސަ ބުނު މަރްޔަމެވެ. އެ ދަރިކަލުން ވާހުށީ ދުނިޔެއާއި އާޚިރަތުގައި ގަދަރު އުފުލިގެންވާ ބޭކަލެއްކަމުގައެވެ. އަދި، ﷲ، ހަޒުރަތަށް ކުއްތަންކުރައްވާފައިވާ ބޭކަލުންގެ ތެރެއިންނެވެ.","",""],["₃ سورة آل عمران","46","وَيُكَلِّمُ ٱلنَّاسَ فِي ٱلۡمَهۡدِ وَكَهۡلٗا وَمِنَ ٱلصَّـٰلِحِينَ ٤٦","ويكلم الناس في المهد وكهلا ومن الصالحين","އަދި، (އެކަލޭގެފާނު ވާހުށީ) ޅަފަތުގެ ދާނުގައްޔާއި، ދުވަސްވެފައިވާ އުމުރު ގައިވެސް، މީސްތަކުންނާ ވާހަކަދައްކަވާ، އަދި، ސާލިހުންގެ ތެރެއިންވާ ބޭކަލެއް ކަމުގައެވެ.","",""],["₃ سورة آل عمران","47","قَالَتۡ رَبِّ أَنَّىٰ يَكُونُ لِي وَلَدٞ وَلَمۡ يَمۡسَسۡنِي بَشَرٞۖ قَالَ كَذَٰلِكِ ٱللَّهُ يَخۡلُقُ مَا يَشَآءُۚ إِذَا قَضَىٰٓ أَمۡرٗا فَإِنَّمَا يَقُولُ لَهُۥ كُن فَيَكُونُ ٤٧","قالت رب أنى يكون لي ولد ولم يمسسني بشر قال كذلك الله يخلق ما يشاء إذا قضى أمرا فإنما يقول له كن فيكون","އެކަމަނާ ދެންނެވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! މިއަޅާޔަށް ދަރިޔަކު ލިބޭނީ ކޮންފަދަޔަކުންތޯއެވެ؟ އެއްވެސް އިންސާނަކު ތިމަންއަޅާގެ ގަޔަކު ނުބީހެއެވެ. އެ މަލާއިކަތާ ވިދާޅުވިއެވެ. (ކަންހުރީ) އެފަދައިންނެވެ. ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ އެއްޗެއް ހައްދަވަތެވެ. އެކަލާނގެ ކަމަކަށް ނިޔާކުރައްވައިފިނަމަ އެކަމަކަށް ވަހީކުރައްވާކަން ކަށަވަރީ، [ވާށޭ] އެވެ! ދެން އެކަމެއް ވެދެއެވެ.","",""],["₃ سورة آل عمران","48","وَيُعَلِّمُهُ ٱلۡكِتَٰبَ وَٱلۡحِكۡمَةَ وَٱلتَّوۡرَىٰةَ وَٱلۡإِنجِيلَ ٤٨","ويعلمه الكتاب والحكمة والتوراة والإنجيل","އަދި، ލިޔުމާއި، ހިކުމަތާއި، ތައުރާތާއި، އިންޖީލު، އެކަލޭގެފާނަށް އެކަލާނގެ އުނގަންނައި ދެއްވާނެތެވެ.","",""],["₃ سورة آل عمران","49","وَرَسُولًا إِلَىٰ بَنِيٓ إِسۡرَـٰٓءِيلَ أَنِّي قَدۡ جِئۡتُكُم بِـَٔايَةٖ مِّن رَّبِّكُمۡ أَنِّيٓ أَخۡلُقُ لَكُم مِّنَ ٱلطِّينِ كَهَيۡـَٔةِ ٱلطَّيۡرِ فَأَنفُخُ فِيهِ فَيَكُونُ طَيۡرَۢا بِإِذۡنِ ٱللَّهِۖ وَأُبۡرِئُ ٱلۡأَكۡمَهَ وَٱلۡأَبۡرَصَ وَأُحۡيِ ٱلۡمَوۡتَىٰ بِإِذۡنِ ٱللَّهِۖ وَأُنَبِّئُكُم بِمَا تَأۡكُلُونَ وَمَا تَدَّخِرُونَ فِي بُيُوتِكُمۡۚ إِنَّ فِي ذَٰلِكَ لَأٓيَةٗ لَّكُمۡ إِن كُنتُم مُّؤۡمِنِينَ ٤٩","ورسولا إلى بني إسرائيل أني قد جئتكم بآية من ربكم أني أخلق لكم من الطين كهيئة الطير فأنفخ فيه فيكون طيرا بإذن الله وأبرئ الأكمه والأبرص وأحيي الموتى بإذن الله وأنبئكم بما تأكلون وما تدخرون في بيوتكم إن في ذلك لآية لكم إن كنتم مؤمنين","އަދި، (އެކަލޭގެފާނު ވާހުށީ) އިސްރާއީލުގެދަރިންގެ ގާތަށް ފޮނުއްވާ ރަސޫލެއް ކަމުގައެވެ. (އެކަލޭގެފާނު އެމީހުންނަށް ވިދާޅުވާނެތެވެ.) ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ގާތަށް ތިމަންކަލޭގެފާނު މިވަޑައިގަތީ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން (ތިމަންކަލޭގެފާނީ ރަސޫލަކު ކަމަށް ހެކިދޭ) ސާފު ދަލީލަކާއިގެންނެވެ. (ފަހެ) ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނު ތިޔަބައިމީހުންނަށް، ދޫނީގެ ސިފައިގައި، މަށިން އެއްޗެއް ހައްދަވައި، އެޔަށް ފުމެލެއްވުމުން، ﷲގެ އިޒުނަފުޅުން އެ އެތި، ދޫންޏަކަށް ވެގެންދާނެތެވެ. އަދި، ތިމަންކަލޭގެފާނު، ﷲގެ އިޒުނަ ފުޅާއެކު، ލޯކަނު މީހުންނާއި، ބަރަޞް ބަލިޖެހިފައިވާ މީހުން، ފަސޭހަކުރައްވައި، މަރުވެފައިވާ މީހުން ދިރުއްވާހުށީމެވެ. އަދި، ތިޔަބައިމީހުން ކައިއުޅޭ ތަކެއްޗާއި، ތިޔަބައިމީހުންގެ ގޭގޭގައި ފަހަށް ރައްކާކުރާ ތަކެތީގެ ވާހަކަ، ތިޔަބައިމީހުންނަށް، ތިމަންކަލޭގެފާނު ކިޔައިދެއްވާހުށީމެވެ. ތިޔަބައިމީހުންނީ، އީމާން ވާބަޔަކުކަމުގައި ވާނަމަ، (ތިމަންކަލޭގެފާނީ ރަސޫލެއްކަމަށް ހެކިދޭ) ސާފު ދަލީލެއް އެކަންތަކުގައި ތިޔަބައިމީހުންނަށް ވާކަން ކަށަވަރެވެ.","",""],["₃ سورة آل عمران","50","وَمُصَدِّقٗا لِّمَا بَيۡنَ يَدَيَّ مِنَ ٱلتَّوۡرَىٰةِ وَلِأُحِلَّ لَكُم بَعۡضَ ٱلَّذِي حُرِّمَ عَلَيۡكُمۡۚ وَجِئۡتُكُم بِـَٔايَةٖ مِّن رَّبِّكُمۡ فَٱتَّقُواْ ٱللَّهَ وَأَطِيعُونِ ٥٠","ومصدقا لما بين يدي من التوراة ولأحل لكم بعض الذي حرم عليكم وجئتكم بآية من ربكم فاتقوا الله وأطيعون","އަދި، (ތިމަންކަލޭގެފާނު މިވަޑައިގަތީ) ތިމަންކަލޭގެފާނުގެ ކުރިން ބާވައިލެއްވި ތައުރާތު ތެދުކުރާ ބޭކަލެއްގެ ގޮތުގައެވެ. އަދި، ތިޔަބައިމީހުންގެ މައްޗަށް (މީގެކުރިން) ހަރާމްކުރައްވާފައިވާ ބައެއް ތަކެތި، ތިޔަބައިމީހުންނަށް ހަލާލުކުރެއްވުމަށްޓަކައެވެ. އަދި، ތިޔަބައިމީހުންގެ ގާތަށް ތިމަންކަލޭގެފާނު މި ވަޑައިގަތީ ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތު ންވާ ސާފު ދަލީލަކާއިގެންނެވެ. ފަހެ، ތިޔަބައިމީހުން، ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި، ތިޔަބައިމީހުން، ތިމަންކަލޭގެފާނަށް ކިޔަމަންވާށެވެ!","",""],["₃ سورة آل عمران","51","إِنَّ ٱللَّهَ رَبِّي وَرَبُّكُمۡ فَٱعۡبُدُوهُۚ هَٰذَا صِرَٰطٞ مُّسۡتَقِيمٞ ٥١","إن الله ربي وربكم فاعبدوه هذا صراط مستقيم","ހަމަކަށަވަރުން، ﷲއީ، ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއެވެ. އަދި، ތިޔަބައިމީހުންގެވެސް ވެރިރަސްކަލާނގެމެއެވެ. ފަހެ، ތިޔަބައިމީހުން، އެކަލާނގެޔަށް އަޅުކަންކުރާށެވެ! މިއީ، ސީދާވެގެންވާ ތެދުމަގެވެ.","",""],["₃ سورة آل عمران","52","۞فَلَمَّآ أَحَسَّ عِيسَىٰ مِنۡهُمُ ٱلۡكُفۡرَ قَالَ مَنۡ أَنصَارِيٓ إِلَى ٱللَّهِۖ قَالَ ٱلۡحَوَارِيُّونَ نَحۡنُ أَنصَارُ ٱللَّهِ ءَامَنَّا بِٱللَّهِ وَٱشۡهَدۡ بِأَنَّا مُسۡلِمُونَ ٥٢","فلما أحس عيسى منهم الكفر قال من أنصاري إلى الله قال الحواريون نحن أنصار الله آمنا بالله واشهد بأنا مسلمون","ފަހެ، އެއުރެންގެ ކިބައިން ކުފުރުވެރިކަން، ޢީސާގެފާނަށް އެނގިވަޑައިގެންނެވި ހިނދު ވިދާޅުވިއެވެ. ﷲއަށްޓަކައި، ތިމަންކަލޭގެފާނަށް ނަސްރު ދޭނީ ކޮންބަޔެއް ހެއްޔެވެ؟ ޙަވާރިއްޔަ ބޭކަލުންގެ މީހުން ދެންނެވޫއެވެ. ތިމަންމެންނީ، ﷲއަށް ނަސްރު ދޭ މީހުންނީމުއެވެ. ތިމަންމެންވަނީ، ﷲއަށް އީމާން ވެގެންނެވެ. އަދި، ތިމަންމެންނީ މުސްލިމުން ކަމުގައި ކަލޭގެފާނު ހެކިވެވަޑައިގަންނަވާށެވެ!","",""],["₃ سورة آل عمران","53","رَبَّنَآ ءَامَنَّا بِمَآ أَنزَلۡتَ وَٱتَّبَعۡنَا ٱلرَّسُولَ فَٱكۡتُبۡنَا مَعَ ٱلشَّـٰهِدِينَ ٥٣","ربنا آمنا بما أنزلت واتبعنا الرسول فاكتبنا مع الشاهدين","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އިބަރަސްކަލާނގެ ބާވައިލެއްވިފޮތަށް އަޅަމެން އީމާން ވެއްޖައީމުއެވެ. އަދި، ރަސޫލު އާޔަށް (އެބަހީ: ޢީސާގެފާނަށް) އަޅަމެން ތަބާ ވެއްޖައީމުއެވެ. ފަހެ، (އިބަރަސްކަލާނގެ އެއްކައުވަންތަކަމަށާއި، ރަސޫލާއީ، އިބަރަސްކަލާނގެ ހައްގު ރަސޫލާ ކަމަށް) ހެކިވާ މީހުންނާ އެކުގައި އަޅަމެން ލިޔުއްވާނދޭވެ!","",""],["₃ سورة آل عمران","54","وَمَكَرُواْ وَمَكَرَ ٱللَّهُۖ وَٱللَّهُ خَيۡرُ ٱلۡمَٰكِرِينَ ٥٤","ومكروا ومكر الله والله خير الماكرين","އެއުރެން (އެބަހީ: ކާފިރުވި މީހުން) މަކަރުވެރި ނުބައި ރޭވުންތައް ރޭވިއެވެ. ﷲ، (އެއުރެންގެ ރޭވުންތައް ބާތިލުކުރައްވައި، އެއުރެންނަށް ކެހިލިބޭނެގޮތަށް) ތަދްބީރުކުރެއްވިއެވެ. ﷲއީ، މަކަރުވެރިންނަށްވުރެ ތަދްބީރުކުރެއްވުން މޮޅު ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","55","إِذۡ قَالَ ٱللَّهُ يَٰعِيسَىٰٓ إِنِّي مُتَوَفِّيكَ وَرَافِعُكَ إِلَيَّ وَمُطَهِّرُكَ مِنَ ٱلَّذِينَ كَفَرُواْ وَجَاعِلُ ٱلَّذِينَ ٱتَّبَعُوكَ فَوۡقَ ٱلَّذِينَ كَفَرُوٓاْ إِلَىٰ يَوۡمِ ٱلۡقِيَٰمَةِۖ ثُمَّ إِلَيَّ مَرۡجِعُكُمۡ فَأَحۡكُمُ بَيۡنَكُمۡ فِيمَا كُنتُمۡ فِيهِ تَخۡتَلِفُونَ ٥٥","إذ قال الله يا عيسى إني متوفيك ورافعك إلي ومطهرك من الذين كفروا وجاعل الذين اتبعوك فوق الذين كفروا إلى يوم القيامة ثم إلي مرجعكم فأحكم بينكم فيما كنتم فيه تختلفون","ﷲ، ވަހީކުރެއްވިހިނދު ހަނދުމަކުރާށެވެ! އޭ ޢީސާގެފާނެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ގެންދަވާހުށީމެވެ. އަދި، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ކަލޭގެފާނު އުފުއްލަވާ ހުށީމެވެ. އަދި، ކާފިރުވި މީހުންގެ ކިބައިން ކަލޭގެފާނު ދުރުކުރައްވައި ސަލާމަތްކުރައްވާ ހުށީމެވެ. އަދި، ކާފިރުވި މީހުންނަށްވުރެ ކަލޭގެފާނަށް ތަބާވި މީހުން ގިޔާމަތް ދުވަހާ ޖެހެންދެން މަތިވެރިކުރައްވާހުށީމެވެ. ދެން، ތިޔަބައިމީހުން އެނބުރި ރުޖޫއަ ވުންވަނީ، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށެވެ. ދެން، ތިޔަބައިމީހުން ޚިލާފު ވެއުޅުނު ކަންތަކާމެދު، ތިޔަބައިމީހުންގެ މެދުގައި ތިމަންރަސްކަލާނގެ ހުކުމްކުރައްވާހުށީމެވެ.","",""],["₃ سورة آل عمران","56","فَأَمَّا ٱلَّذِينَ كَفَرُواْ فَأُعَذِّبُهُمۡ عَذَابٗا شَدِيدٗا فِي ٱلدُّنۡيَا وَٱلۡأٓخِرَةِ وَمَا لَهُم مِّن نَّـٰصِرِينَ ٥٦","فأما الذين كفروا فأعذبهم عذابا شديدا في الدنيا والآخرة وما لهم من ناصرين","ފަހެ، ކާފިރުވި މީހުން ދަންނާށެވެ! ފަހެ، ދުނިޔެއާއި އާޚިރަތުގައި، ގަދަފަދަވެގެންވާ އަޒާބަކުން ތިމަންރަސްކަލާނގެ އެއުރެންނަށް އަޒާބު ދެއްވާ ހުށީމެވެ. އަދި، އެއުރެންނަށް ނަސްރު ދޭނޭ އެއްވެސް ބަޔަކު ނުވެއެވެ.","",""],["₃ سورة آل عمران","57","وَأَمَّا ٱلَّذِينَ ءَامَنُواْ وَعَمِلُواْ ٱلصَّـٰلِحَٰتِ فَيُوَفِّيهِمۡ أُجُورَهُمۡۗ وَٱللَّهُ لَا يُحِبُّ ٱلظَّـٰلِمِينَ ٥٧","وأما الذين آمنوا وعملوا الصالحات فيوفيهم أجورهم والله لا يحب الظالمين","އަދި، އީމާންވެ، ސާލިހު ޢަމަލުކުޅަމީހުން ދަންނާށެވެ! ފަހެ، އެއުރެންގެ އުޖޫރަ ފުރިހަމަޔަށް އެއުރެންނަށް، އެކަލާނގެ ދެއްވާނެތެވެ. އަނިޔާވެރިންދެކެ ﷲ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["₃ سورة آل عمران","58","ذَٰلِكَ نَتۡلُوهُ عَلَيۡكَ مِنَ ٱلۡأٓيَٰتِ وَٱلذِّكۡرِ ٱلۡحَكِيمِ ٥٨","ذلك نتلوه عليك من الآيات والذكر الحكيم","މިއީ، ފާޅުވެގެންވާ ދަލީލު ތަކާއި، ހިކުމަތް ތެރި ޛިކުރުގެ ތެރެއިން (އެބަހީ: ކީރިތި ގުރްއާނުން) ކަލޭގެފާނަށް، ތިމަންރަސްކަލާނގެ ކިޔައިދެއްވާ ވާހަކަތަކެކެވެ.","",""],["₃ سورة آل عمران","59","إِنَّ مَثَلَ عِيسَىٰ عِندَ ٱللَّهِ كَمَثَلِ ءَادَمَۖ خَلَقَهُۥ مِن تُرَابٖ ثُمَّ قَالَ لَهُۥ كُن فَيَكُونُ ٥٩","إن مثل عيسى عند الله كمثل آدم خلقه من تراب ثم قال له كن فيكون","ހަމަކަށަވަރުން، ﷲގެ ހަޒުރަތުގައި، ޢީސާގެފާނު (ހެއްދެވުމުގެ) މިސާލު، އާދަމުގެފާނުގެ މިސާލު ފަދައެވެ. އެކަލާނގެ، އާދަމުގެފާނު ހެއްދެވީ، ވެލީންނެވެ. ދެން، އެކަލޭގެފާނަށް (އިންސާނަކަށް) [ވާށޭ] ވަހީކުރެއްވިއެވެ. ދެން، (ﷲ ވަހީކުރެއްވި ފަދައިން) ވެއްޖެއެވެ.","",""],["₃ سورة آل عمران","60","ٱلۡحَقُّ مِن رَّبِّكَ فَلَا تَكُن مِّنَ ٱلۡمُمۡتَرِينَ ٦٠","الحق من ربك فلا تكن من الممترين","(އެއީ) ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތު ންވާ ހައްގު ތެދު ބަސްފުޅެވެ. ފަހެ، ޝައްކުކުރާ މީހުންގެ ތެރެއިން، ކަލޭގެފާނު ވެވަޑައިނުގަންނަވާށެވެ!","",""],["₃ سورة آل عمران","61","فَمَنۡ حَآجَّكَ فِيهِ مِنۢ بَعۡدِ مَا جَآءَكَ مِنَ ٱلۡعِلۡمِ فَقُلۡ تَعَالَوۡاْ نَدۡعُ أَبۡنَآءَنَا وَأَبۡنَآءَكُمۡ وَنِسَآءَنَا وَنِسَآءَكُمۡ وَأَنفُسَنَا وَأَنفُسَكُمۡ ثُمَّ نَبۡتَهِلۡ فَنَجۡعَل لَّعۡنَتَ ٱللَّهِ عَلَى ٱلۡكَٰذِبِينَ ٦١","فمن حاجك فيه من بعد ما جاءك من العلم فقل تعالوا ندع أبناءنا وأبناءكم ونساءنا ونساءكم وأنفسنا وأنفسكم ثم نبتهل فنجعل لعنت الله على الكاذبين","ފަހެ، ކަލޭގެފާނަށް އިލްމުގެ ތެރެއިން (ޢީސާގެފާނާމެދު) އައި އެއްޗެއްގެ ފަހުން، އެކަލޭގެފާނާ މެދުގައި ކަލޭގެފާނާ ޖަދަލުކުރި (ނަސާރާ އިންގެ) މީހުންނަށް ވިދާޅުވާށެވެ! އަހަރެމެންގެ ދަރިންނަށާއި، ތިޔަބައިމީހުންގެ ދަރިންނަށް އަދި، އަހަރެމެންގެ އަންހެނުންނަށާއި، ތިޔަބައިމީހުންގެ އަންހެނުންނަށް އަދި، އަހަރެމެންގެ އަމިއްލަ ނަފްސު ތަކަށާއި، ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތަކަށް، އަހަރެމެން ގޮވައި އެއްކުރަމާ އަންނާށެވެ! ދެން، ދޮގުވެރިންގެ މައްޗަށް ﷲގެ ލައުނަތް ލެއްވުމަށްއެދި، އަހަރެމެން ދުއާ ކޮށް އިބްތިހާލުކުރާނީއެވެ.","",""],["₃ سورة آل عمران","62","إِنَّ هَٰذَا لَهُوَ ٱلۡقَصَصُ ٱلۡحَقُّۚ وَمَا مِنۡ إِلَٰهٍ إِلَّا ٱللَّهُۚ وَإِنَّ ٱللَّهَ لَهُوَ ٱلۡعَزِيزُ ٱلۡحَكِيمُ ٦٢","إن هذا لهو القصص الحق وما من إله إلا الله وإن الله لهو العزيز الحكيم","ހަމަކަށަވަރުންވެސް، މިއީ ހައްގު ތެދު ވާހަކަތަކެކެވެ. އަދި، ﷲ މެނުވީ، އެއްވެސް އިލާހަކު ނުވެއެވެ. އަދި، ހަމަކަށަވަރުންވެސް، ﷲއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","63","فَإِن تَوَلَّوۡاْ فَإِنَّ ٱللَّهَ عَلِيمُۢ بِٱلۡمُفۡسِدِينَ ٦٣","فإن تولوا فإن الله عليم بالمفسدين","ފަހެ، އެއުރެން، (އިންކާރު ކޮށް) އެނބުރި ފުރަގަސްދީފިނަމަ، (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ފަސާދަކުރާ މީހުން މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","64","قُلۡ يَـٰٓأَهۡلَ ٱلۡكِتَٰبِ تَعَالَوۡاْ إِلَىٰ كَلِمَةٖ سَوَآءِۭ بَيۡنَنَا وَبَيۡنَكُمۡ أَلَّا نَعۡبُدَ إِلَّا ٱللَّهَ وَلَا نُشۡرِكَ بِهِۦ شَيۡـٔٗا وَلَا يَتَّخِذَ بَعۡضُنَا بَعۡضًا أَرۡبَابٗا مِّن دُونِ ٱللَّهِۚ فَإِن تَوَلَّوۡاْ فَقُولُواْ ٱشۡهَدُواْ بِأَنَّا مُسۡلِمُونَ ٦٤","قل يا أهل الكتاب تعالوا إلى كلمة سواء بيننا وبينكم ألا نعبد إلا الله ولا نشرك به شيئا ولا يتخذ بعضنا بعضا أربابا من دون الله فإن تولوا فقولوا اشهدوا بأنا مسلمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ ފޮތުގެ އަހުލުވެރިންނޭވެ! އަހުރެމެންގެ މެދުގައްޔާއި ތިޔަބައިމީހުންގެ މެދުގައި، ހަމަހަމަވެ، އެއްގޮތްވެގެންވާ ކަލިމަކަށް އަންނާށެވެ! (އެއީ) ﷲއަށް މެނުވީ، އަހުރެމެން އަޅުކަން ނުކުޅައުމެވެ. އަދި، އެކަލާނގެޔާ އެއްވެސް އެއްޗެއް އަހުރެމެން ޝަރީކު ނުކުޅައުމެވެ. އަދި، އަހުރެމެންގެ އެއްބަޔަކު އަނެއްބަޔަކީ ﷲ ފިޔަވައި ކަލާނގެތަކެއް ކަމުގައި ނުހެދުމެވެ. ފަހެ، އެއުރެން (އެކަމާ) ދެކޮޅުހަދައި، ފުރަގަސްދީފިނަމަ، (އެއުރެންނަށް) ތިޔަބައިމީހުން ބުނާށެވެ! ހަމަކަށަވަރުން، ތިމަންމެންނީ މުސްލިމުން ކަމުގައި ތިޔަބައިމީހުން ހެކިވާށެވެ!","",""],["₃ سورة آل عمران","65","يَـٰٓأَهۡلَ ٱلۡكِتَٰبِ لِمَ تُحَآجُّونَ فِيٓ إِبۡرَٰهِيمَ وَمَآ أُنزِلَتِ ٱلتَّوۡرَىٰةُ وَٱلۡإِنجِيلُ إِلَّا مِنۢ بَعۡدِهِۦٓۚ أَفَلَا تَعۡقِلُونَ ٦٥","يا أهل الكتاب لم تحاجون في إبراهيم وما أنزلت التوراة والإنجيل إلا من بعده أفلا تعقلون","އޭ ފޮތުގެ އަހުލުވެރިންނޭވެ! އިބްރާހީމްގެފާނަށް ފަހުގައި މެނުވީ، ތައުރާތާއި، އިންޖީލު ބާވައިލައްވާފައި ނުވާއިރު، އިބްރާހީމްގެފާނާ މެދުގައި ތިޔަބައިމީހުން ޖަދަލު ކުރަނީ ކީއްވެގެން ހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުންނަކަށް ނުވިސްނޭހެއްޔެވެ؟","",""],["₃ سورة آل عمران","66","هَـٰٓأَنتُمۡ هَـٰٓؤُلَآءِ حَٰجَجۡتُمۡ فِيمَا لَكُم بِهِۦ عِلۡمٞ فَلِمَ تُحَآجُّونَ فِيمَا لَيۡسَ لَكُم بِهِۦ عِلۡمٞۚ وَٱللَّهُ يَعۡلَمُ وَأَنتُمۡ لَا تَعۡلَمُونَ ٦٦","ها أنتم هؤلاء حاججتم فيما لكم به علم فلم تحاجون فيما ليس لكم به علم والله يعلم وأنتم لا تعلمون","ބަލަ! ތިޔަބައިމީހުން އެކަމެއްގެ އިލްމު ތިޔަބައިމީހުންނަށް ލިބިގެންވާ ކަމަކާމެދުގައި ޖަދަލުކޮށްފީމުއެވެ. ދެން، އެކަމެއްގެ އިލްމު ތިޔަބައިމީހުންނަށް ލިބިގެންނުވާ ކަމަކާ މެދުގައި ޖަދަލުކުރަނީ ކީއްވެގެންހެއްޔެވެ؟ (އެކަންތައް) ދެނެވޮޑިގެންވަނީ ﷲއެވެ. ތިޔަބައިމީހުންނަކަށް ނޭނގެއެވެ.","",""],["₃ سورة آل عمران","67","مَا كَانَ إِبۡرَٰهِيمُ يَهُودِيّٗا وَلَا نَصۡرَانِيّٗا وَلَٰكِن كَانَ حَنِيفٗا مُّسۡلِمٗا وَمَا كَانَ مِنَ ٱلۡمُشۡرِكِينَ ٦٧","ما كان إبراهيم يهوديا ولا نصرانيا ولكن كان حنيفا مسلما وما كان من المشركين","ޔަހޫދީއެއް ކަމުގައިވެސް އަދި، ނަސްރާނީއެއް ކަމުގައިވެސް އިބްރާހީމްގެފާނު ނުވެއެވެ. އަދި، ކިއެއްތަ! އެކަލޭގެފާނު ވަނީ ބާތިލު މަގުން އެއްކިބާވެ، ހައްގު ދީނަށް ތަބާ ވެގެންވާ މުސްލިމަކު ކަމުގައެވެ. އަދި، ޝަރީކުކުރާ މީހުންގެ ތެރެއަކުންވެސް އެކަލޭގެފާނު ނުވެއެވެ.","",""],["₃ سورة آل عمران","68","إِنَّ أَوۡلَى ٱلنَّاسِ بِإِبۡرَٰهِيمَ لَلَّذِينَ ٱتَّبَعُوهُ وَهَٰذَا ٱلنَّبِيُّ وَٱلَّذِينَ ءَامَنُواْۗ وَٱللَّهُ وَلِيُّ ٱلۡمُؤۡمِنِينَ ٦٨","إن أولى الناس بإبراهيم للذين اتبعوه وهذا النبي والذين آمنوا والله ولي المؤمنين","ހަމަކަށަވަރުން، މީސްތަކުންކުރެ، އިބްރާހީމްގެފާނަށް (ނިސްބަތް ވުމުގައި) އެންމެ އައުލާ ކަން ބޮޑީ، އެކަލޭގެފާނަށް ތަބާ ވީ މީހުންނާއި، މި ނަބިއްޔާއާއި، (އެބަހީ: މުޙައްމަދުގެފާނާއި) އީމާންވި މީހުންނެވެ. ﷲއީ، އީމާންވި މީހުންނަށް އެހީތެރިވެ ވާގިވެރިވެ ވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","69","وَدَّت طَّآئِفَةٞ مِّنۡ أَهۡلِ ٱلۡكِتَٰبِ لَوۡ يُضِلُّونَكُمۡ وَمَا يُضِلُّونَ إِلَّآ أَنفُسَهُمۡ وَمَا يَشۡعُرُونَ ٦٩","ودت طائفة من أهل الكتاب لو يضلونكم وما يضلون إلا أنفسهم وما يشعرون","ފޮތުގެ އަހުލުވެރިންގެ ތެރެއިން ބަޔަކު، ތިޔަބައިމީހުން މަގުފުރައްދައިލެވޭނެ ނަމައޭ ހިތައި، އެކަމަށް އެދުނެވެ. އެއުރެންގެ އަމިއްލަ ނަފްސުތައް މެނުވީ، އެއުރެންނަކަށް މަގުފުރައްދައެއް ނުލެވެތެވެ. އަދި، އެއުރެންނަކަށް (އެކަމެއް) ނޭނގެއެވެ.","",""],["₃ سورة آل عمران","70","يَـٰٓأَهۡلَ ٱلۡكِتَٰبِ لِمَ تَكۡفُرُونَ بِـَٔايَٰتِ ٱللَّهِ وَأَنتُمۡ تَشۡهَدُونَ ٧٠","يا أهل الكتاب لم تكفرون بآيات الله وأنتم تشهدون","އޭ ފޮތުގެ އަހުލުވެރިންނޭވެ! ތިޔަބައިމީހުން (އެއީ ހައްގު ކަން އެނގިތިބެ އެކަމަށް) ހެކިވާ ޙާލު، ﷲގެ އާޔަތްތަކަށް ތިޔަބައިމީހުން ކާފިރު ވަނީ ކީއްވެގެން ހެއްޔެވެ؟","",""],["₃ سورة آل عمران","71","يَـٰٓأَهۡلَ ٱلۡكِتَٰبِ لِمَ تَلۡبِسُونَ ٱلۡحَقَّ بِٱلۡبَٰطِلِ وَتَكۡتُمُونَ ٱلۡحَقَّ وَأَنتُمۡ تَعۡلَمُونَ ٧١","يا أهل الكتاب لم تلبسون الحق بالباطل وتكتمون الحق وأنتم تعلمون","އޭ ފޮތުގެ އަހުލުވެރިންނޭވެ! (އެއީ ހައްގު ކަން) ތިޔަބައިމީހުންނަށް އެނގިތިބި ޙާލުގައި، ހައްގާއި ބާތިލު އޮޅުވާލައި އަދި، ހައްގު ގޮތް ތިޔަބައިމީހުން ފޮރުވަނީ ކީއްވެގެން ހެއްޔެވެ؟","",""],["₃ سورة آل عمران","72","وَقَالَت طَّآئِفَةٞ مِّنۡ أَهۡلِ ٱلۡكِتَٰبِ ءَامِنُواْ بِٱلَّذِيٓ أُنزِلَ عَلَى ٱلَّذِينَ ءَامَنُواْ وَجۡهَ ٱلنَّهَارِ وَٱكۡفُرُوٓاْ ءَاخِرَهُۥ لَعَلَّهُمۡ يَرۡجِعُونَ ٧٢","وقالت طائفة من أهل الكتاب آمنوا بالذي أنزل على الذين آمنوا وجه النهار واكفروا آخره لعلهم يرجعون","ފޮތުގެ އަހުލުވެރިންގެ ތެރެއިން ބަޔަކު (އެއުރެންގެ އަނެއްބަޔަކާ ދިމާޔަށް) ބުންޏެވެ. އީމާންވި މީހުންނަށް ބާވައިލެއްވި އެއްޗަކަށް (އެބަހީ: ކީރިތި ގުރްއާނަށް) ދުވާލުގެ ކުރީކޮޅުގައި ތިޔަބައިމީހުން އީމާން ވާށެވެ! ދެން، އެދުވަހުގެ ފަހުކޮޅުގައި ތިޔަބައިމީހުން (އެޔަށް) ކާފިރު ވާށެވެ! އެއީ، އެއުރެން (އެބަހީ: މުއުމިނުން އެއުރެންގެ ދީނުން) އެނބުރި ރުޖޫއަ ވޭތޯއެވެ!","",""],["₃ سورة آل عمران","73","وَلَا تُؤۡمِنُوٓاْ إِلَّا لِمَن تَبِعَ دِينَكُمۡ قُلۡ إِنَّ ٱلۡهُدَىٰ هُدَى ٱللَّهِ أَن يُؤۡتَىٰٓ أَحَدٞ مِّثۡلَ مَآ أُوتِيتُمۡ أَوۡ يُحَآجُّوكُمۡ عِندَ رَبِّكُمۡۗ قُلۡ إِنَّ ٱلۡفَضۡلَ بِيَدِ ٱللَّهِ يُؤۡتِيهِ مَن يَشَآءُۗ وَٱللَّهُ وَٰسِعٌ عَلِيمٞ ٧٣","ولا تؤمنوا إلا لمن تبع دينكم قل إن الهدى هدى الله أن يؤتى أحد مثل ما أوتيتم أو يحاجوكم عند ربكم قل إن الفضل بيد الله يؤتيه من يشاء والله واسع عليم","އަދި، (އެއުރެން ބުނޫއެވެ.) ތިޔަބައިމީހުންގެ ދީނަށް ތަބާ ވީ މީހަކަށް މެނުވީ، ތިޔަބައިމީހުން އީމާން ނުވާށެވެ! ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ތެދުމަގަކީ ﷲގެ ތެދުމަގެވެ. ތިޔަބައިމީހުންނަށް ދެއްވާފައިވާފަދަ ކަމެއް އެހެން އެއްވެސް މީހަކަށް ދެއްވާފައިވާކަމަށް، (ތިޔަބައިމީހުން ގަބޫލު ނުކުރާށެވެ!) އެހެންނޫންނަމަ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި އެއުރެން (އެބަހީ: މުއުމިނުން) ތިޔަބައިމީހުން ހުއްޖަތުން ދެރަކޮށްފާނެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ފަޟްލު ވަންތަކަންވަނީ، ﷲގެ އަތްޕުޅުގައެވެ. އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް އެކަމެއް ދެއްވަތެވެ. ﷲއީ، ތަނަވަސްވަންތަ މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","74","يَخۡتَصُّ بِرَحۡمَتِهِۦ مَن يَشَآءُۗ وَٱللَّهُ ذُو ٱلۡفَضۡلِ ٱلۡعَظِيمِ ٧٤","يختص برحمته من يشاء والله ذو الفضل العظيم","އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް، އެކަލާނގެ ރަހުމަތް ހާއްސަކުރައްވަތެވެ. އަދި، ﷲއީ، ބޮޑުވެގެންވާ ފަޟްލު ވަންތަކަމުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","75","۞وَمِنۡ أَهۡلِ ٱلۡكِتَٰبِ مَنۡ إِن تَأۡمَنۡهُ بِقِنطَارٖ يُؤَدِّهِۦٓ إِلَيۡكَ وَمِنۡهُم مَّنۡ إِن تَأۡمَنۡهُ بِدِينَارٖ لَّا يُؤَدِّهِۦٓ إِلَيۡكَ إِلَّا مَا دُمۡتَ عَلَيۡهِ قَآئِمٗاۗ ذَٰلِكَ بِأَنَّهُمۡ قَالُواْ لَيۡسَ عَلَيۡنَا فِي ٱلۡأُمِّيِّـۧنَ سَبِيلٞ وَيَقُولُونَ عَلَى ٱللَّهِ ٱلۡكَذِبَ وَهُمۡ يَعۡلَمُونَ ٧٥","ومن أهل الكتاب من إن تأمنه بقنطار يؤده إليك ومنهم من إن تأمنه بدينار لا يؤده إليك إلا ما دمت عليه قائما ذلك بأنهم قالوا ليس علينا في الأميين سبيل ويقولون على الله الكذب وهم يعلمون","ނުހަނު ގިނަ މުދަލަކުން ކަލޭގެފާނު އެމީހަކާ އަމާނަތް ޙަވާލުކުރައްވައިފިނަމަ، އެ އަމާނަތް ކަލޭގެފާނަށް އަނބުރައި ރައްދުކުރާ މީހުން ފޮތުގެ އަހުލުވެރިންގެ ތެރެއިންވެއެވެ. އަދި، ދީނާރަކުން ކަލޭގެފާނު އެމީހަކާ އަމާނަތް ޙަވާލުކުރައްވައިފިނަމަ، (އެ އަމާނަތް އަނބުރައި ރައްދުކުރުން އެދިވަޑައިގެން) އެކަމުގެ މަތީގައި ކަލޭގެފާނު ގާއިމު ވެވަޑައިގެން ހުންނެވިއްޔާ މެނުވީ، އެ އަމާނަތް ކަލޭގެފާނަށް އަނބުރައި ރައްދު ނުކުރާ މީހުންވެސް އެއުރެންގެ ތެރެއިންވެއެވެ. އެއީ، ހަމަކަށަވަރުން، އެއުރެން ބުނެއުޅެނީ އުއްމީންނާ މެދުގައި، (އެބަހީ: އަރަބީންނާ މެދުގައި) އެހެން ހެދުމަކުން އެއްވެސް ފާފައެއް އަހަރެމެންގެ މައްޗަކަށް ނެތެވެ. ފަހެ، އެއުރެން ދެނެތިބެ ﷲއާމެދު ދޮގުބަސްތައް ބުނަނީއެވެ.","",""],["₃ سورة آل عمران","76","بَلَىٰۚ مَنۡ أَوۡفَىٰ بِعَهۡدِهِۦ وَٱتَّقَىٰ فَإِنَّ ٱللَّهَ يُحِبُّ ٱلۡمُتَّقِينَ ٧٦","بلى من أوفى بعهده واتقى فإن الله يحب المتقين","އެހެންނަކުންނޫނެވެ! އެމީހެއްގެ އަހުދު އެމީހަކު ފުރިހަމަޔަށް އަދާކޮށް، ތަގުވާވެރިވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ތަގުވާވެރިންދެކެ ﷲ ލޯބިވެވޮޑިގެންވެތެވެ.","",""],["₃ سورة آل عمران","77","إِنَّ ٱلَّذِينَ يَشۡتَرُونَ بِعَهۡدِ ٱللَّهِ وَأَيۡمَٰنِهِمۡ ثَمَنٗا قَلِيلًا أُوْلَـٰٓئِكَ لَا خَلَٰقَ لَهُمۡ فِي ٱلۡأٓخِرَةِ وَلَا يُكَلِّمُهُمُ ٱللَّهُ وَلَا يَنظُرُ إِلَيۡهِمۡ يَوۡمَ ٱلۡقِيَٰمَةِ وَلَا يُزَكِّيهِمۡ وَلَهُمۡ عَذَابٌ أَلِيمٞ ٧٧","إن الذين يشترون بعهد الله وأيمانهم ثمنا قليلا أولئك لا خلاق لهم في الآخرة ولا يكلمهم الله ولا ينظر إليهم يوم القيامة ولا يزكيهم ولهم عذاب أليم","ހަމަކަށަވަރުން، ﷲގެ އަހުދާއި، އެއުރެންގެ ހުވާތަކަށް ކުޑަ އަގެއް ގަނެއުޅޭ މީހުންނީ އާޚިރަތުގައި އެއުރެންނަށް އެއްވެސް ނަސީބެއް ނެތްބަޔެކެވެ. އަދި، ގިޔާމަތް ދުވަހުން، ﷲ، އެއުރެންނަކަށް ބަސް ވަހީއެއް ނުކުރައްވާނެތެވެ. އަދި، އެއުރެންނަކަށް ބައްލަވާވޮޑިއެއްވެސް ނުގަންނަވާނެތެވެ. އަދި، (ފާފައިން) އެއުރެން ތާހިރެއް ނުކުރައްވާނެތެވެ. އަދި، އެއުރެންނަށް ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["₃ سورة آل عمران","78","وَإِنَّ مِنۡهُمۡ لَفَرِيقٗا يَلۡوُۥنَ أَلۡسِنَتَهُم بِٱلۡكِتَٰبِ لِتَحۡسَبُوهُ مِنَ ٱلۡكِتَٰبِ وَمَا هُوَ مِنَ ٱلۡكِتَٰبِ وَيَقُولُونَ هُوَ مِنۡ عِندِ ٱللَّهِ وَمَا هُوَ مِنۡ عِندِ ٱللَّهِ وَيَقُولُونَ عَلَى ٱللَّهِ ٱلۡكَذِبَ وَهُمۡ يَعۡلَمُونَ ٧٨","وإن منهم لفريقا يلوون ألسنتهم بالكتاب لتحسبوه من الكتاب وما هو من الكتاب ويقولون هو من عند الله وما هو من عند الله ويقولون على الله الكذب وهم يعلمون","އެއީ، ފޮތުން ބައެއްކަމަށް ތިޔަބައިމީހުންނަށް ހީވާނޭގޮތަށް އެއުރެންގެ ދޫތަކުން އޮޅުވާލައި، ބަދަލުކޮށްލައިގެން ފޮތުން ކިޔައިދޭ ބަޔަކު އެއުރެންގެ ތެރެއިން ވާކަން ކަށަވަރެވެ. އެއީ، ފޮތުން ބައެއްކަމުގައިނުވާ ޙާލު ގައެވެ. އަދި، އެއީ ﷲގެ ހަޒުރަތުން ބާވައިލެއްވި އެއްޗެއްކަމުގައި އެއުރެން ބުނެތެވެ. އެއީ، ﷲގެ ހަޒުރަތުން ބާވައިލެއްވި އެއްޗެއް ކަމުގައި ނުވާ ޙާލު ގައެވެ. އަދި، އެއުރެން ދެނެތިބެ ﷲއާމެދު ދޮގުބަސްތައް ބުނަނީއެވެ.","",""],["₃ سورة آل عمران","79","مَا كَانَ لِبَشَرٍ أَن يُؤۡتِيَهُ ٱللَّهُ ٱلۡكِتَٰبَ وَٱلۡحُكۡمَ وَٱلنُّبُوَّةَ ثُمَّ يَقُولَ لِلنَّاسِ كُونُواْ عِبَادٗا لِّي مِن دُونِ ٱللَّهِ وَلَٰكِن كُونُواْ رَبَّـٰنِيِّـۧنَ بِمَا كُنتُمۡ تُعَلِّمُونَ ٱلۡكِتَٰبَ وَبِمَا كُنتُمۡ تَدۡرُسُونَ ٧٩","ما كان لبشر أن يؤتيه الله الكتاب والحكم والنبوة ثم يقول للناس كونوا عبادا لي من دون الله ولكن كونوا ربانيين بما كنتم تعلمون الكتاب وبما كنتم تدرسون","ﷲ، އެމީހަކަށް ފޮތާއި، ހިކުމަތާއި، ނަބީކަން ދެއްވީމާ، ދެން، ﷲ ފިޔަވައި ތިމަންނާއަށް އަޅުކަން ކުރާމީހުން ކަމުގައި ތިޔަބައިމީހުންވާށޭ މީސްތަކުންނަށް ބުނުމަކީ، (އެކަންތައްތައް ދެއްވި) އެއްވެސް އިންސާނަކަށް އެކަށީގެންވާ ކަމެއް ނޫނެވެ. އެހެނެއްކަމަކު (އެމީހަކު ބުނާހުށީ) ތިޔަބައިމީހުން ފޮތުން އުނގަންނައިދީ އުޅުނު ތަކެތީގެ ސަބަބުންނާއި، ތިޔަބައިމީހުން އުނގެނި ދަސްކޮށް އުޅުނު ތަކެތީގެ ސަބަބުން، ތިޔަބައިމީހުން ރައްބާނީންނަށް (އެބަހީ: ދީންވެރި އިލްމުވެރިންނަށް) ވާށޭއެވެ!","",""],["₃ سورة آل عمران","80","وَلَا يَأۡمُرَكُمۡ أَن تَتَّخِذُواْ ٱلۡمَلَـٰٓئِكَةَ وَٱلنَّبِيِّـۧنَ أَرۡبَابًاۗ أَيَأۡمُرُكُم بِٱلۡكُفۡرِ بَعۡدَ إِذۡ أَنتُم مُّسۡلِمُونَ ٨٠","ولا يأمركم أن تتخذوا الملائكة والنبيين أربابا أيأمركم بالكفر بعد إذ أنتم مسلمون","އަދި، މަލާއިކަތްނާއި، ނަބިއްޔުންނީ، އިލާހުން ކަމުގައި ހަދައިގެން އުޅުމަކަށް އެމީހަކު ތިޔަބައިމީހުންނަކަށް އަމުރުކުރުމެއްވެސް ނެތެވެ. ތިޔަބައިމީހުން މުސްލިމުން ކަމުގައިވެގެން ތިބުމަށްފަހު، ކާފިރު ވުމަށް އެމީހަކު ތިޔަބައިމީހުންނަށް (ފަހެ) އަމުރުކުރާނެ ހެއްޔެވެ؟","",""],["₃ سورة آل عمران","81","وَإِذۡ أَخَذَ ٱللَّهُ مِيثَٰقَ ٱلنَّبِيِّـۧنَ لَمَآ ءَاتَيۡتُكُم مِّن كِتَٰبٖ وَحِكۡمَةٖ ثُمَّ جَآءَكُمۡ رَسُولٞ مُّصَدِّقٞ لِّمَا مَعَكُمۡ لَتُؤۡمِنُنَّ بِهِۦ وَلَتَنصُرُنَّهُۥۚ قَالَ ءَأَقۡرَرۡتُمۡ وَأَخَذۡتُمۡ عَلَىٰ ذَٰلِكُمۡ إِصۡرِيۖ قَالُوٓاْ أَقۡرَرۡنَاۚ قَالَ فَٱشۡهَدُواْ وَأَنَا۠ مَعَكُم مِّنَ ٱلشَّـٰهِدِينَ ٨١","وإذ أخذ الله ميثاق النبيين لما آتيتكم من كتاب وحكمة ثم جاءكم رسول مصدق لما معكم لتؤمنن به ولتنصرنه قال أأقررتم وأخذتم على ذلكم إصري قالوا أقررنا قال فاشهدوا وأنا معكم من الشاهدين","ނަބިއްޔުންގެ ކިބައިން، ﷲ ކަށަވަރުވެގެންވާ އަހުދު ހިއްޕެވިހިނދު (ކަންހިނގިގޮތް ހަނދުމަކުރާށެވެ! އެހިނދު ﷲ އެންގެވިއެވެ.) ތިމަންރަސްކަލާނގެ ތިޔަބޭކަލުންނަށް ފޮތާއި ހިކުމަތް ދެއްވީމާ ދެން ތިޔަބޭކަލުންގެ ގާތުގައިވާ އެއްޗެއް ތެދުކުރައްވާ ރަސޫލަކު ތިޔަބޭކަލުންގެ ގާތަށް ވަޑައިގަތުމުން، ހަމަކަށަވަރުން، ތިޔަބޭކަލުން، އެބޭކަލަކަށް އީމާންވާ ހުށިކަމެވެ! އަދި، ހަމަކަށަވަރުން، އެބޭކަލަކަށް ތިޔަބޭކަލުން ނަސްރު ދޭހުށިކަމެވެ! އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ތިޔަބޭކަލުން އިގްރާރުވެ، އެކަމުގެ މައްޗަށް ތިމަންރަސްކަލާނގެއަށް ކަށަވަރުވެގެންވާ އަހުދު ހިފައިފީމުހެއްޔެވެ؟ އެބޭކަލުން ދެންނެވިއެވެ. އަޅަމެން އިގްރާރުވެއްޖައީމުއެވެ. އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ފަހެ، ތިޔަބޭކަލުން (އެކަމަށް) ހެކިވާށެވެ! ހެކިވާމީހުންގެ ތެރެއިން ތިޔަބޭކަލުންނާ އެކުގައި ތިމަންރަސްކަލާނގެ ވޮޑިގެންވަމެވެ.","",""],["₃ سورة آل عمران","82","فَمَن تَوَلَّىٰ بَعۡدَ ذَٰلِكَ فَأُوْلَـٰٓئِكَ هُمُ ٱلۡفَٰسِقُونَ ٨٢","فمن تولى بعد ذلك فأولئك هم الفاسقون","ދެން، އެއަށްފަހު (އެ އަހުދު އުވާލައި) ފުރަގަސްދީފި މީހާ، (ދަންނާށެވެ!) ފަހެ، އެއުރެންނަކީ ހަމަ ފާސިގުންނެވެ.","",""],["₃ سورة آل عمران","83","أَفَغَيۡرَ دِينِ ٱللَّهِ يَبۡغُونَ وَلَهُۥٓ أَسۡلَمَ مَن فِي ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ طَوۡعٗا وَكَرۡهٗا وَإِلَيۡهِ يُرۡجَعُونَ ٨٣","أفغير دين الله يبغون وله أسلم من في السماوات والأرض طوعا وكرها وإليه يرجعون","އުޑުތަކާއި، ބިމުގައިވާހާ ބަޔަކު ރުހުމުގައްޔާއި، ނުރުހުމުގައި އެކަލާނގެޔަށް، ކިޔަމަންވެގެންވާއިރު، އެއުރެން (އެބަހީ: އެނބުރި ފުރަގަސްދިން މީހުން) އެ އެދެނީ ﷲގެ ދީން ފިޔަވައި އެހެން ދީނެއް ހެއްޔެވެ؟ އަދި، އެއުރެން އެނބުރި ރުޖޫއަކުރައްވާހުށީ، އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["₃ سورة آل عمران","84","قُلۡ ءَامَنَّا بِٱللَّهِ وَمَآ أُنزِلَ عَلَيۡنَا وَمَآ أُنزِلَ عَلَىٰٓ إِبۡرَٰهِيمَ وَإِسۡمَٰعِيلَ وَإِسۡحَٰقَ وَيَعۡقُوبَ وَٱلۡأَسۡبَاطِ وَمَآ أُوتِيَ مُوسَىٰ وَعِيسَىٰ وَٱلنَّبِيُّونَ مِن رَّبِّهِمۡ لَا نُفَرِّقُ بَيۡنَ أَحَدٖ مِّنۡهُمۡ وَنَحۡنُ لَهُۥ مُسۡلِمُونَ ٨٤","قل آمنا بالله وما أنزل علينا وما أنزل على إبراهيم وإسماعيل وإسحاق ويعقوب والأسباط وما أوتي موسى وعيسى والنبيون من ربهم لا نفرق بين أحد منهم ونحن له مسلمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންމެން ﷲއަށާއި، އަދި ތިމަންމެންގެ މައްޗަށް ބާވައިލެއްވި އެއްޗަކަށް އީމާން ވެއްޖައީމުއެވެ. އަދި، އިބްރާހީމްގެފާނާއި، އިސްމާޢީލުގެފާނާއި، އިސްޙާގުގެފާނާއި، ޔައުގޫބުގެފާނާއި، އެކަލޭގެފާނުގެ ދަރިކޮޅަށް ބާވައިލެއްވި އެއްޗަކަށާއި، މޫސާގެފާނާއި، ޢީސާގެފާނާއި، އެނޫންވެސް ނަބީބޭކަލުންނަށް، އެބޭކަލުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ދެއްވި އެއްޗަކަށްވެސްމެއެވެ. އެބޭކަލުންގެ ތެރެއިން އެއްވެސްބޭކަލަކާ މެދުގައި ތިމަންމެން ތަފާތެއް ނުކުރަމުއެވެ. އަދި، ތިމަންމެންވަނީ އެކަލާނގެޔަށް ބޯލަނބައި ކިޔަމަންވެގެންނެވެ.","",""],["₃ سورة آل عمران","85","وَمَن يَبۡتَغِ غَيۡرَ ٱلۡإِسۡلَٰمِ دِينٗا فَلَن يُقۡبَلَ مِنۡهُ وَهُوَ فِي ٱلۡأٓخِرَةِ مِنَ ٱلۡخَٰسِرِينَ ٨٥","ومن يبتغ غير الإسلام دينا فلن يقبل منه وهو في الآخرة من الخاسرين","ދީނެއްގެ ގޮތުގައި އިސްލާމް ދީން ނޫން ދީނެއް އެދޭމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާގެ ކިބައިން (އެކަން) ގަބޫލެއް ނުކުރައްވާ ހުށްޓެވެ. އަދި، އާޚިރަތުގައި އޭނާ ވާހުށީ، ގެއްލެނިވެގެންވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["₃ سورة آل عمران","86","كَيۡفَ يَهۡدِي ٱللَّهُ قَوۡمٗا كَفَرُواْ بَعۡدَ إِيمَٰنِهِمۡ وَشَهِدُوٓاْ أَنَّ ٱلرَّسُولَ حَقّٞ وَجَآءَهُمُ ٱلۡبَيِّنَٰتُۚ وَٱللَّهُ لَا يَهۡدِي ٱلۡقَوۡمَ ٱلظَّـٰلِمِينَ ٨٦","كيف يهدي الله قوما كفروا بعد إيمانهم وشهدوا أن الرسول حق وجاءهم البينات والله لا يهدي القوم الظالمين","އެބަޔަކު އީމާން ވުމަށްފަހު، އަދި ހަމަކަށަވަރުން، ރަސޫލާއީ ހައްގު ރަސޫލާ ކަމަށް ހެކިވުމަށްފަހު، އަދި ފާޅުވެގެންވާ ދަލީލުތައް އެއުރެންނާ ހަމަޔަށް އައުމަށްފަހު، ކާފިރުވި ބަޔަކަށް، ﷲ ތެދުމަގު ދައްކަވާނީ ކިހިނަކުންހެއްޔެވެ؟ އަނިޔާވެރި ވެގެންވާ ގައުމަކަށް ﷲ ތެދުމަގެއް ނުދައްކަވަތެވެ.","",""],["₃ سورة آل عمران","87","أُوْلَـٰٓئِكَ جَزَآؤُهُمۡ أَنَّ عَلَيۡهِمۡ لَعۡنَةَ ٱللَّهِ وَٱلۡمَلَـٰٓئِكَةِ وَٱلنَّاسِ أَجۡمَعِينَ ٨٧","أولئك جزاؤهم أن عليهم لعنة الله والملائكة والناس أجمعين","އެއުރެންގެ ޖަޒާއަކީ، ހަމަކަށަވަރުން ﷲއާއި، މަލާއިކަތްނާއި، އެންމެހައި މީސްތަކުންގެ ލައުނަތެއުރެންގެ މައްޗަށް ލެއްވުމެވެ.","",""],["₃ سورة آل عمران","88","خَٰلِدِينَ فِيهَا لَا يُخَفَّفُ عَنۡهُمُ ٱلۡعَذَابُ وَلَا هُمۡ يُنظَرُونَ ٨٨","خالدين فيها لا يخفف عنهم العذاب ولا هم ينظرون","އެއުރެން، އެ ލައުނަތުގައި ދެމިތިބެނިވި ގޮތުގައެވެ. އެއުރެންގެ ކިބަޔަކުން އަޒާބެއް ލުޔެއް ނުކުރައްވާނެތެވެ. އަދި، އެއުރެންނަށް (އަޒާބު ލިބުމުގައި) ލަހެއްވެސް ނުމެކުރައްވާނެތެވެ.","",""],["₃ سورة آل عمران","89","إِلَّا ٱلَّذِينَ تَابُواْ مِنۢ بَعۡدِ ذَٰلِكَ وَأَصۡلَحُواْ فَإِنَّ ٱللَّهَ غَفُورٞ رَّحِيمٌ ٨٩","إلا الذين تابوا من بعد ذلك وأصلحوا فإن الله غفور رحيم","އެއަށްފަހު، ތައުބާވެ (ޢަމަލުތައް) އިސްލާހު ކޮށްފި މީހުން މެނުވީއެވެ. ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފުފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","90","إِنَّ ٱلَّذِينَ كَفَرُواْ بَعۡدَ إِيمَٰنِهِمۡ ثُمَّ ٱزۡدَادُواْ كُفۡرٗا لَّن تُقۡبَلَ تَوۡبَتُهُمۡ وَأُوْلَـٰٓئِكَ هُمُ ٱلضَّآلُّونَ ٩٠","إن الذين كفروا بعد إيمانهم ثم ازدادوا كفرا لن تقبل توبتهم وأولئك هم الضالون","ހަމަކަށަވަރުން، އެއުރެން އީމާން ވުމަށްފަހު، ކާފިރުވެ، ދެން ކާފިރު ކަން އިތުރުވީ މީހުންގެ ތައުބާ ގަބޫލު ނުކުރައްވާހުށްޓެވެ. އަދި، އެއުރެންނަކީ ހަމަ މަގުފުރެދިފައިވާ މީހުންނެވެ.","",""],["₃ سورة آل عمران","91","إِنَّ ٱلَّذِينَ كَفَرُواْ وَمَاتُواْ وَهُمۡ كُفَّارٞ فَلَن يُقۡبَلَ مِنۡ أَحَدِهِم مِّلۡءُ ٱلۡأَرۡضِ ذَهَبٗا وَلَوِ ٱفۡتَدَىٰ بِهِۦٓۗ أُوْلَـٰٓئِكَ لَهُمۡ عَذَابٌ أَلِيمٞ وَمَا لَهُم مِّن نَّـٰصِرِينَ ٩١","إن الذين كفروا وماتوا وهم كفار فلن يقبل من أحدهم ملء الأرض ذهبا ولو افتدى به أولئك لهم عذاب أليم وما لهم من ناصرين","ހަމަކަށަވަރުން، ކާފިރުވެ، އަދި ކާފިރުން ކަމުގައިތިބެ މަރުވި މީހުން ބިން ފުރޭހައި ރަނުން ފިދުޔަ ދިން ކަމުގައިވިޔަސް، އެއިން އެކެއްގެ ކިބައިންވެސް އެކަން ގަބޫލު ނުކުރައްވާހުށްޓެވެ. އެއުރެންނަށް، ވޭންދެނިވި އަޒާބު ހުށްޓެވެ. އަދި، އެއުރެންނަށް ނަސްރު ދޭނޭ އެއްވެސްބަޔަކު ނުވެއެވެ.","",""],["₃ سورة آل عمران","92","لَن تَنَالُواْ ٱلۡبِرَّ حَتَّىٰ تُنفِقُواْ مِمَّا تُحِبُّونَۚ وَمَا تُنفِقُواْ مِن شَيۡءٖ فَإِنَّ ٱللَّهَ بِهِۦ عَلِيمٞ ٩٢","لن تنالوا البر حتى تنفقوا مما تحبون وما تنفقوا من شيء فإن الله به عليم","ތިޔަބައިމީހުން، ލޯބިވާ އެއްޗަކުން ތިޔަބައިމީހުން ހޭދަކޮށްފުމަށްދާނދެން، ތިޔަބައިމީހުންނަކަށް ހެވެއް ނުލިބޭނެތެވެ. އަދި، ތިޔަބައިމީހުން ހޭދަކުރާ ކޮންމެ އެއްޗެއް، ފަހެ، ހަމަކަށަވަރުން، ﷲ އެ އެއްޗެއް މޮޅަށް ދެނެވޮޑިގެންވެތެވެ.","",""],["₃ سورة آل عمران","93","۞كُلُّ ٱلطَّعَامِ كَانَ حِلّٗا لِّبَنِيٓ إِسۡرَـٰٓءِيلَ إِلَّا مَا حَرَّمَ إِسۡرَـٰٓءِيلُ عَلَىٰ نَفۡسِهِۦ مِن قَبۡلِ أَن تُنَزَّلَ ٱلتَّوۡرَىٰةُۚ قُلۡ فَأۡتُواْ بِٱلتَّوۡرَىٰةِ فَٱتۡلُوهَآ إِن كُنتُمۡ صَٰدِقِينَ ٩٣","كل الطعام كان حلا لبني إسرائيل إلا ما حرم إسرائيل على نفسه من قبل أن تنزل التوراة قل فأتوا بالتوراة فاتلوها إن كنتم صادقين","ތައުރާތު ބާވައިލެއްވުމުގެ ކުރިން، އިސްރާއީލުގެފާނު އެކަލޭގެފާނުގެ އަމިއްލަ ނަފްސުގެ މައްޗަށް ހަރާމްކުރެއްވި ތަކެތި ފިޔަވައި، އެންމެހާ ކާތަކެތި އެއީ، އިސްރާއީލުގެދަރިންނަށް ހަލާލު ތަކެތި ކަމުގައިވިއެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ތެދުވެރިންކަމުގައި ވަނީނަމަ، ފަހެ، ތިޔަބައިމީހުން ތައުރާތުގެނެސް އެ ކިޔައިބަލާށެވެ!","",""],["₃ سورة آل عمران","94","فَمَنِ ٱفۡتَرَىٰ عَلَى ٱللَّهِ ٱلۡكَذِبَ مِنۢ بَعۡدِ ذَٰلِكَ فَأُوْلَـٰٓئِكَ هُمُ ٱلظَّـٰلِمُونَ ٩٤","فمن افترى على الله الكذب من بعد ذلك فأولئك هم الظالمون","އެޔަށްފަހު، ﷲއާމެދު ހަދައިގެން ދޮގު ބުނިމީހާ، (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ، ހަމަ އަނިޔާވެރިންނެވެ.","",""],["₃ سورة آل عمران","95","قُلۡ صَدَقَ ٱللَّهُۗ فَٱتَّبِعُواْ مِلَّةَ إِبۡرَٰهِيمَ حَنِيفٗاۖ وَمَا كَانَ مِنَ ٱلۡمُشۡرِكِينَ ٩٥","قل صدق الله فاتبعوا ملة إبراهيم حنيفا وما كان من المشركين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲ ވަހީކުރެއްވީ ތެދުބަސްފުޅެވެ. ފަހެ، ބާތިލު މަގުން އެއްކިބާވެ، ހައްގުގެ މަގަށް ތަބާ ވެގެންވާ އިބްރާހީމްގެފާނުންގެ ދީނަށް ތިޔަބައިމީހުން ތަބާ ވާށެވެ! އަދި، އެކަލޭގެފާނު މުޝްރިކުންގެ ތެރެޔަކުން ނުވެއެވެ.","",""],["₃ سورة آل عمران","96","إِنَّ أَوَّلَ بَيۡتٖ وُضِعَ لِلنَّاسِ لَلَّذِي بِبَكَّةَ مُبَارَكٗا وَهُدٗى لِّلۡعَٰلَمِينَ ٩٦","إن أول بيت وضع للناس للذي ببكة مباركا وهدى للعالمين","ހަމަކަށަވަރުން، މީސްތަކުންނަށްޓަކައި ފުރަތަމަ ލެއްވި، (އަޅުކަމުގެ) ގެޔަކީ، މައްކާ ގައިވާ ގެފުޅުކަން ކަށަވަރެވެ. ބަރަކާތް ލައްވާފައިވާ ތަނެއްގެ ގޮތުގައެވެ. އަދި، އާލަމްތަކަށް ތެދުމަގެއް ކަމުގައެވެ.","",""],["₃ سورة آل عمران","97","فِيهِ ءَايَٰتُۢ بَيِّنَٰتٞ مَّقَامُ إِبۡرَٰهِيمَۖ وَمَن دَخَلَهُۥ كَانَ ءَامِنٗاۗ وَلِلَّهِ عَلَى ٱلنَّاسِ حِجُّ ٱلۡبَيۡتِ مَنِ ٱسۡتَطَاعَ إِلَيۡهِ سَبِيلٗاۚ وَمَن كَفَرَ فَإِنَّ ٱللَّهَ غَنِيٌّ عَنِ ٱلۡعَٰلَمِينَ ٩٧","فيه آيات بينات مقام إبراهيم ومن دخله كان آمنا ولله على الناس حج البيت من استطاع إليه سبيلا ومن كفر فإن الله غني عن العالمين","ފާޅުވެގެންވާ ހެކިތަކެއް އެތާނގައި ވެއެވެ. އިބްރާހީމްގެފާނު ހުންނެވިތަން (އޭގެތެރެއިން) ވެއެވެ. އެތަނަށް (އެބަހީ: ގެފުޅުގެ ހަރަމް ފުޅަށް) ވަދެއްޖެ މީހާއީ، އަމާން ކަން ލިބިގެންވާ މީހަކު ކަމުގައިވިއެވެ. އެކަމަށް މަގެއްފެނި ކުޅަދާނަވެއްޖެ މީހާ، އެ ގެފުޅަށް ގަސްދު ކޮށްގެންދިއުމީ، (އެބަހީ: ހައްޖު ވުމަކީ) ﷲއަށްޓަކައި މީސްތަކުންގެ މައްޗަށްއޮތް ވާޖިބެކެވެ. (އެކަމާމެދު) ދެކޮޅުހަދައިފި މީހާ، (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، އެންމެހާ އާލަމްތައް ފިޔަވައި، ފުދިވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","98","قُلۡ يَـٰٓأَهۡلَ ٱلۡكِتَٰبِ لِمَ تَكۡفُرُونَ بِـَٔايَٰتِ ٱللَّهِ وَٱللَّهُ شَهِيدٌ عَلَىٰ مَا تَعۡمَلُونَ ٩٨","قل يا أهل الكتاب لم تكفرون بآيات الله والله شهيد على ما تعملون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ ފޮތުގެ އަހުލުވެރިންނޭވެ! ތިޔަބައިމީހުން ﷲގެ އާޔަތްތަކަށް ކާފިރު ވަނީ ކީއްވެގެންހެއްޔެވެ؟ ﷲއީ، ތިޔަބައިމީހުންކުރާ ކަންތަކުގެ މައްޗަށް ހެކިވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","99","قُلۡ يَـٰٓأَهۡلَ ٱلۡكِتَٰبِ لِمَ تَصُدُّونَ عَن سَبِيلِ ٱللَّهِ مَنۡ ءَامَنَ تَبۡغُونَهَا عِوَجٗا وَأَنتُمۡ شُهَدَآءُۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا تَعۡمَلُونَ ٩٩","قل يا أهل الكتاب لم تصدون عن سبيل الله من آمن تبغونها عوجا وأنتم شهداء وما الله بغافل عما تعملون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ ފޮތުގެ އަހުލުވެރިންނޭވެ! ތިޔަބައިމީހުން، އީމާންވި މީހަކު ﷲގެ މަގުން އެއްކިބާކުރަނީ، ކީއްވެގެން ހެއްޔެވެ؟ (އެ މަގަކީ ﷲގެ ތެދުމަގުކަމަށް) ތިޔަބައިމީހުން ހެކިވެތިބެ، އެ މަގު ގުދުކޮށް އޮތުމަށް ތިޔަބައިމީހުން އެދެނީއެވެ. ތިޔަބައިމީހުންކުރާ ޢަމަލު ތަކާމެދު، ﷲ ޣާފިލު ވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["₃ سورة آل عمران","100","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ إِن تُطِيعُواْ فَرِيقٗا مِّنَ ٱلَّذِينَ أُوتُواْ ٱلۡكِتَٰبَ يَرُدُّوكُم بَعۡدَ إِيمَٰنِكُمۡ كَٰفِرِينَ ١٠٠","يا أيها الذين آمنوا إن تطيعوا فريقا من الذين أوتوا الكتاب يردوكم بعد إيمانكم كافرين","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ފޮތް ލިބުނު މީހުންގެ ތެރެއިން ބަޔަކަށް، ތިޔަބައިމީހުން ކިޔަމަންވާނަމަ، (ތިޔަބައިމީހުންގެ) އީމާންކަމަށްފަހު، އެއުރެން ތިޔަބައިމީހުންނީ އަލުން ކާފިރުން ކަމުގައި ރައްދުކުރާނެތެވެ.","",""],["₃ سورة آل عمران","101","وَكَيۡفَ تَكۡفُرُونَ وَأَنتُمۡ تُتۡلَىٰ عَلَيۡكُمۡ ءَايَٰتُ ٱللَّهِ وَفِيكُمۡ رَسُولُهُۥۗ وَمَن يَعۡتَصِم بِٱللَّهِ فَقَدۡ هُدِيَ إِلَىٰ صِرَٰطٖ مُّسۡتَقِيمٖ ١٠١","وكيف تكفرون وأنتم تتلى عليكم آيات الله وفيكم رسوله ومن يعتصم بالله فقد هدي إلى صراط مستقيم","އަދި، ﷲ ބާވައިލެއްވި އާޔަތްތައް ތިޔަބައިމީހުންނަށް ކިޔަވައިދެއްވަނިކޮށް އަދި، ތިޔަބައިމީހުންގެ ތެރޭގައި އެކަލާނގެ ރަސޫލާ ހުންނަވަނިކޮށް، ތިޔަބައިމީހުން ކާފިރު ވަނީ ކޮންފަދަޔަކުން ހެއްޔެވެ؟ ﷲގެ ދީންގައި ހިފަހައްޓާ މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް ސީދާވެގެންވާ މަގަކަށް ތެދުމަގު ލިބިއްޖެކަން ކަށަވަރެވެ.","",""],["₃ سورة آل عمران","102","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ ٱتَّقُواْ ٱللَّهَ حَقَّ تُقَاتِهِۦ وَلَا تَمُوتُنَّ إِلَّا وَأَنتُم مُّسۡلِمُونَ ١٠٢","يا أيها الذين آمنوا اتقوا الله حق تقاته ولا تموتن إلا وأنتم مسلمون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! އެކަލާނގެއަށް ތަގުވާވެރިވުން ހައްގު ވެގެންވާ ގޮތުގައި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި، މުސްލިމުން ކަމުގައިވާ ޙާލުގައި މެނުވީ، ތިޔަބައިމީހުން މަރުނުވާހުށިކަމެވެ!","",""],["₃ سورة آل عمران","103","وَٱعۡتَصِمُواْ بِحَبۡلِ ٱللَّهِ جَمِيعٗا وَلَا تَفَرَّقُواْۚ وَٱذۡكُرُواْ نِعۡمَتَ ٱللَّهِ عَلَيۡكُمۡ إِذۡ كُنتُمۡ أَعۡدَآءٗ فَأَلَّفَ بَيۡنَ قُلُوبِكُمۡ فَأَصۡبَحۡتُم بِنِعۡمَتِهِۦٓ إِخۡوَٰنٗا وَكُنتُمۡ عَلَىٰ شَفَا حُفۡرَةٖ مِّنَ ٱلنَّارِ فَأَنقَذَكُم مِّنۡهَاۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمۡ ءَايَٰتِهِۦ لَعَلَّكُمۡ تَهۡتَدُونَ ١٠٣","واعتصموا بحبل الله جميعا ولا تفرقوا واذكروا نعمت الله عليكم إذ كنتم أعداء فألف بين قلوبكم فأصبحتم بنعمته إخوانا وكنتم على شفا حفرة من النار فأنقذكم منها كذلك يبين الله لكم آياته لعلكم تهتدون","ތިޔަބައިމީހުން އެންމެން ﷲގެ ދީންގައި ހިފަހައްޓާށެވެ! އަދި، ވަކިވަކިވެ ނުގަންނާށެވެ! އަދި، ﷲ ތިޔަބައިމީހުންނަށް ދެއްވި ނިއުމަތް ތިޔަބައިމީހުން ހަނދުމަކުރާށެވެ! އެހެނީ، ތިޔަބައިމީހުން އަދާވަތް ތެރިން ކަމުގައިވަނިކޮށް، އެކަލާނގެ ތިޔަބައިމީހުންގެ ހިތްތައް އެކުވެރި ކުރެއްވިއެވެ. ދެން، އެކަލާނގެ ދެއްވި ނިއުމަތްގެ ސަބަބުން ތިޔަބައިމީހުންނީ އަޚުންތަކެއް ކަމުގައި ވެއްޖައީމުއެވެ. އަދި، ތިޔަބައިމީހުން ނަރަކައިގެ ވަޅުގަނޑެއްގެ ތުންފަތްމަތީގައި ވީމުއެވެ. ދެން، އެކަލާނގެ ތިޔަބައިމީހުން އެއިން ސަލާމަތްކުރެއްވިއެވެ. ﷲ، އެކަލާނގެ އާޔަތްތައް ތިޔަބައިމީހުންނަށް ބަޔާންކޮށްދެއްވަނީ، އެފަދައިންނެވެ. (އެއީ) ތިޔަބައިމީހުން ތެދުމަގު ލިބިގަތުމަށްޓަކައެވެ.","",""],["₃ سورة آل عمران","104","وَلۡتَكُن مِّنكُمۡ أُمَّةٞ يَدۡعُونَ إِلَى ٱلۡخَيۡرِ وَيَأۡمُرُونَ بِٱلۡمَعۡرُوفِ وَيَنۡهَوۡنَ عَنِ ٱلۡمُنكَرِۚ وَأُوْلَـٰٓئِكَ هُمُ ٱلۡمُفۡلِحُونَ ١٠٤","ولتكن منكم أمة يدعون إلى الخير ويأمرون بالمعروف وينهون عن المنكر وأولئك هم المفلحون","ހެޔޮކަމުގެ މަގަށް ގޮވާ، އަދި ހެޔޮކަންތަކަށް އަމުރުކުރާ، އަދި ނުބައިކަންތައް ނަހީކުރާ ބަޔަކު ތިޔަބައިމީހުންގެ ތެރެއިން ވާހުށިކަމެވެ! އެއުރެންނަކީ ހަމަ، ދިންނަވާނޭ މީހުންނެވެ.","",""],["₃ سورة آل عمران","105","وَلَا تَكُونُواْ كَٱلَّذِينَ تَفَرَّقُواْ وَٱخۡتَلَفُواْ مِنۢ بَعۡدِ مَا جَآءَهُمُ ٱلۡبَيِّنَٰتُۚ وَأُوْلَـٰٓئِكَ لَهُمۡ عَذَابٌ عَظِيمٞ ١٠٥","ولا تكونوا كالذين تفرقوا واختلفوا من بعد ما جاءهم البينات وأولئك لهم عذاب عظيم","ފާޅުވެގެންވާ ހެކިތައް އެއުރެންނަށް އައުމަށްފަހު، ވަކިވަކިވެ ޚިލާފު ވީ މީހުން ފަދައިން، ތިޔަބައިމީހުން ނުވާށެވެ! ބޮޑުވެގެންވާ އަޒާބެއް އެއުރެންނަށް ހުށްޓެވެ.","",""],["₃ سورة آل عمران","106","يَوۡمَ تَبۡيَضُّ وُجُوهٞ وَتَسۡوَدُّ وُجُوهٞۚ فَأَمَّا ٱلَّذِينَ ٱسۡوَدَّتۡ وُجُوهُهُمۡ أَكَفَرۡتُم بَعۡدَ إِيمَٰنِكُمۡ فَذُوقُواْ ٱلۡعَذَابَ بِمَا كُنتُمۡ تَكۡفُرُونَ ١٠٦","يوم تبيض وجوه وتسود وجوه فأما الذين اسودت وجوههم أكفرتم بعد إيمانكم فذوقوا العذاب بما كنتم تكفرون","(އެއީ) މޫނުތަކެއް އަލިވެ، އަދި މޫނުތަކެއް އަނދިރިވެގެންދާ ދުވަހެވެ. ފަހެ، އެއުރެންގެ މޫނުތައް އަނދިރިވެގެންދިޔަ މީހުން ދަންނާށެވެ! (އެއުރެންނާ ދިމާޔަށް އެދުވަހުން ބުނެވޭހުށްޓެވެ.) ތިޔަބައިމީހުން، އީމާން ވުމަށްފަހު، ތިޔަބައިމީހުން ކާފިރު ވީހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުން ކާފިރުވެ އުޅުނުކަމަށްޓަކައި އަޒާބުގެ ރަހަ ތިޔަބައިމީހުން ލިބިގަންނާށެވެ!","",""],["₃ سورة آل عمران","107","وَأَمَّا ٱلَّذِينَ ٱبۡيَضَّتۡ وُجُوهُهُمۡ فَفِي رَحۡمَةِ ٱللَّهِۖ هُمۡ فِيهَا خَٰلِدُونَ ١٠٧","وأما الذين ابيضت وجوههم ففي رحمة الله هم فيها خالدون","އަދި، އެއުރެންގެ މޫނުތައް އަލިވެގެންދިޔަ މީހުން ދަންނާށެވެ! ފަހެ، އެއުރެންވަނީ ﷲގެ ރަހުމަތް ގައެވެ. އެއުރެންނީ އެ ރަހުމަތުގައި ދެމިތިބެނިވި ބަޔެކެވެ.","",""],["₃ سورة آل عمران","108","تِلۡكَ ءَايَٰتُ ٱللَّهِ نَتۡلُوهَا عَلَيۡكَ بِٱلۡحَقِّۗ وَمَا ٱللَّهُ يُرِيدُ ظُلۡمٗا لِّلۡعَٰلَمِينَ ١٠٨","تلك آيات الله نتلوها عليك بالحق وما الله يريد ظلما للعالمين","އެއީ، ﷲގެ އާޔަތް ތަކެވެ. ހައްގު ގޮތުގައި ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް އެ އާޔަތްތައް ކިޔައިދެއްވަމެވެ. އަދި، އެއްވެސް މަޚްލޫގަކަށް އަނިޔާއެއް ދެއްވުމަކަށް ﷲ އިރާދައެއް ނުކުރައްވަތެވެ.","",""],["₃ سورة آل عمران","109","وَلِلَّهِ مَا فِي ٱلسَّمَٰوَٰتِ وَمَا فِي ٱلۡأَرۡضِۚ وَإِلَى ٱللَّهِ تُرۡجَعُ ٱلۡأُمُورُ ١٠٩","ولله ما في السماوات وما في الأرض وإلى الله ترجع الأمور","އަދި، އުޑުތަކާއި، ބިމުގައި ވާހާ އެއްޗެއް މިލްކުވެގެންވަނީ، ﷲއަށެވެ. އަދި، އެންމެހާ ކަންތައް ރުޖޫއަކުރައްވާހުށީ ﷲގެ ހަޒުރަތަށެވެ.","",""],["₃ سورة آل عمران","110","كُنتُمۡ خَيۡرَ أُمَّةٍ أُخۡرِجَتۡ لِلنَّاسِ تَأۡمُرُونَ بِٱلۡمَعۡرُوفِ وَتَنۡهَوۡنَ عَنِ ٱلۡمُنكَرِ وَتُؤۡمِنُونَ بِٱللَّهِۗ وَلَوۡ ءَامَنَ أَهۡلُ ٱلۡكِتَٰبِ لَكَانَ خَيۡرٗا لَّهُمۚ مِّنۡهُمُ ٱلۡمُؤۡمِنُونَ وَأَكۡثَرُهُمُ ٱلۡفَٰسِقُونَ ١١٠","كنتم خير أمة أخرجت للناس تأمرون بالمعروف وتنهون عن المنكر وتؤمنون بالله ولو آمن أهل الكتاب لكان خيرا لهم منهم المؤمنون وأكثرهم الفاسقون","މީސްތަކުންނަށްޓަކައި ނެރުއްވި، އެންމެ ހެޔޮ އުއްމަތްކަމުގައި ތިޔަބައިމީހުން ވީމުއެވެ. (އެހެނީ) ތިޔަބައިމީހުން ހެޔޮކަންތަކަށް އަމުރުކުރަމުއެވެ. އަދި، ނުބައިކަންތައް ނަހީކުރަމުއެވެ. އަދި، ތިޔަބައިމީހުން ﷲއަށް އީމާން ވަމުއެވެ. ފޮތުގެ އަހުލުވެރިން އީމާން ވީނަމަ، އެއުރެންނަށް އެގޮތް ހެޔޮކަން ބޮޑުވީސްކަން ކަށަވަރެވެ. އެއުރެންގެ ތެރެއިން އީމާން ވެގެންތިބި މީހުންވެއެވެ. އަދި، އޭގެތެރެއިން ގިނަމީހުންނީ ފާސިގުންނެވެ.","",""],["₃ سورة آل عمران","111","لَن يَضُرُّوكُمۡ إِلَّآ أَذٗىۖ وَإِن يُقَٰتِلُوكُمۡ يُوَلُّوكُمُ ٱلۡأَدۡبَارَ ثُمَّ لَا يُنصَرُونَ ١١١","لن يضروكم إلا أذى وإن يقاتلوكم يولوكم الأدبار ثم لا ينصرون","އުނދަގޫކުރުންނޫން އެހެންގޮތަކުން އެއުރެންނަކަށް ތިޔަބައިމީހުންނަށް ގެއްލުމެއް ނުދެވޭނެތެވެ. އަދި، އެއުރެން ތިޔަބައިމީހުންނާ ހަނގުރާމަ ކުރާނަމަ، ތިޔަބައިމީހުންނަށް ފުރަގަސްދީ (ބަލިވެގެން) އެއުރެން ހިނގައިދާނެތެވެ. ދެން، އެއުރެންނަކަށް ނަސްރެއް ނުލިބޭނެތެވެ.","",""],["₃ سورة آل عمران","112","ضُرِبَتۡ عَلَيۡهِمُ ٱلذِّلَّةُ أَيۡنَ مَا ثُقِفُوٓاْ إِلَّا بِحَبۡلٖ مِّنَ ٱللَّهِ وَحَبۡلٖ مِّنَ ٱلنَّاسِ وَبَآءُو بِغَضَبٖ مِّنَ ٱللَّهِ وَضُرِبَتۡ عَلَيۡهِمُ ٱلۡمَسۡكَنَةُۚ ذَٰلِكَ بِأَنَّهُمۡ كَانُواْ يَكۡفُرُونَ بِـَٔايَٰتِ ٱللَّهِ وَيَقۡتُلُونَ ٱلۡأَنۢبِيَآءَ بِغَيۡرِ حَقّٖۚ ذَٰلِكَ بِمَا عَصَواْ وَّكَانُواْ يَعۡتَدُونَ ١١٢","ضربت عليهم الذلة أين ما ثقفوا إلا بحبل من الله وحبل من الناس وباءوا بغضب من الله وضربت عليهم المسكنة ذلك بأنهم كانوا يكفرون بآيات الله ويقتلون الأنبياء بغير حق ذلك بما عصوا وكانوا يعتدون","އެއުރެންވީ، ކޮންމެތަނެއްގައިވެސް، އެއުރެންގެ މައްޗަށް ދެރަކަމާއި، ނިކަމެތިކަން ލައްވާފައިވެއެވެ. ﷲގެ އަހުދަކުން ނުވަތަ މީސްތަކުންގެ އަހުދަކުން (ރައްކާތެރިކަން ލިބިގެންފުމުން) މެނުވީއެވެ. އަދި، ﷲގެ ކޯފާއާއިގެން އެއުރެން އެނބުރި އަޔެވެ. އަދި، މިސްކީނު ކަން އެއުރެންގެ މައްޗަށް ލައްވާފައިވިއެވެ. އެއީ، އެއުރެން ﷲގެ އާޔަތްތަކަށް ކާފިރުވެ އަދި، ހައްގަކާ ނުލައި، ނަބިއްޔުން ގަތުލު ކޮށް އުޅުނުކަމަށްޓަކައެވެ. އެއީ، އެއުރެން އުރެދުނުކަމަށްޓަކައެވެ. އަދި، އުރެދުމުގައި ހައްދުފަހަނަޅައިދާކަމުގައި އެއުރެން ވީކަމަށްޓަކައެވެ.","",""],["₃ سورة آل عمران","113","۞لَيۡسُواْ سَوَآءٗۗ مِّنۡ أَهۡلِ ٱلۡكِتَٰبِ أُمَّةٞ قَآئِمَةٞ يَتۡلُونَ ءَايَٰتِ ٱللَّهِ ءَانَآءَ ٱلَّيۡلِ وَهُمۡ يَسۡجُدُونَ ١١٣","ليسوا سواء من أهل الكتاب أمة قائمة يتلون آيات الله آناء الليل وهم يسجدون","އެއުރެން، ހަމަހަމަވެގެނެއް ނުވެއެވެ. ފޮތުގެ އަހުލުވެރިންގެ ތެރެއިން ސީދާކަންމަތީ ގާއިމުވެ ތިބޭ ބަޔަކުވެއެވެ. އެއުރެން ރޭގަނޑުގެ ވަގުތުތަކުގައި ސަޖިދަ ކޮށް ނަމާދުކުރާ ޙާލު، ﷲ ބާވައިލެއްވި އާޔަތްތައް ކިޔަވަތެވެ.","",""],["₃ سورة آل عمران","114","يُؤۡمِنُونَ بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِ وَيَأۡمُرُونَ بِٱلۡمَعۡرُوفِ وَيَنۡهَوۡنَ عَنِ ٱلۡمُنكَرِ وَيُسَٰرِعُونَ فِي ٱلۡخَيۡرَٰتِۖ وَأُوْلَـٰٓئِكَ مِنَ ٱلصَّـٰلِحِينَ ١١٤","يؤمنون بالله واليوم الآخر ويأمرون بالمعروف وينهون عن المنكر ويسارعون في الخيرات وأولئك من الصالحين","ﷲއަށާއި، އާޚިރަތް ދުވަހަށް އެއުރެން އީމާން ވެތެވެ. އަދި، އެއުރެން ހެޔޮކަންތަކަށް އަމުރު ކޮށް، ނުބައިކަންތައް ނަހީކުރެތެވެ. އަދި، ހެޔޮކަންތައް ކުރުމަށް އެއުރެން އަވަސްވެގަނެތެވެ. އެއުރެންވަނީ ސާލިހުންގެ ތެރެއިންނެވެ.","",""],["₃ سورة آل عمران","115","وَمَا يَفۡعَلُواْ مِنۡ خَيۡرٖ فَلَن يُكۡفَرُوهُۗ وَٱللَّهُ عَلِيمُۢ بِٱلۡمُتَّقِينَ ١١٥","وما يفعلوا من خير فلن يكفروه والله عليم بالمتقين","ހެޔޮކަމުގެ ތެރެއިން އެއުރެންކުރާ އެއްވެސްކަމެއް، ފަހެ، އެކަމެއްގެ ސަވާބުން އެއުރެން މަޙްރޫމު ނުކުރައްވާހުށްޓެވެ. ﷲއީ، ތަގުވާވެރިން މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","116","إِنَّ ٱلَّذِينَ كَفَرُواْ لَن تُغۡنِيَ عَنۡهُمۡ أَمۡوَٰلُهُمۡ وَلَآ أَوۡلَٰدُهُم مِّنَ ٱللَّهِ شَيۡـٔٗاۖ وَأُوْلَـٰٓئِكَ أَصۡحَٰبُ ٱلنَّارِۖ هُمۡ فِيهَا خَٰلِدُونَ ١١٦","إن الذين كفروا لن تغني عنهم أموالهم ولا أولادهم من الله شيئا وأولئك أصحاب النار هم فيها خالدون","ހަމަކަށަވަރުން، ކާފިރުވި މީހުންނަކަށް އެއުރެންގެ މުދާތަކެއްވެސް އަދި، އެއުރެންގެ ދަރިންތަކެއްވެސް، އެއުރެންނަށްޓަކައި، ﷲގެ ހަޒުރަތުން އެއްވެސް ކަމެއް ފުއްދައެއް ނުދޭނެތެވެ. އަދި، އެއުރެންނީ ނަރަކައިގެ އަހުލުވެރިންނެވެ. އެއުރެންނީ އެތާނގައި ދެމިތިބެނިވި ބަޔެކެވެ.","",""],["₃ سورة آل عمران","117","مَثَلُ مَا يُنفِقُونَ فِي هَٰذِهِ ٱلۡحَيَوٰةِ ٱلدُّنۡيَا كَمَثَلِ رِيحٖ فِيهَا صِرٌّ أَصَابَتۡ حَرۡثَ قَوۡمٖ ظَلَمُوٓاْ أَنفُسَهُمۡ فَأَهۡلَكَتۡهُۚ وَمَا ظَلَمَهُمُ ٱللَّهُ وَلَٰكِنۡ أَنفُسَهُمۡ يَظۡلِمُونَ ١١٧","مثل ما ينفقون في هذه الحياة الدنيا كمثل ريح فيها صر أصابت حرث قوم ظلموا أنفسهم فأهلكته وما ظلمهم الله ولكن أنفسهم يظلمون","މި ދުނިޔޭގެ ހަޔާތުގައި، އެއުރެން (އެބަހީ: ކާފިރުވި މީހުން) ހޭދަކުރާ އެއްޗެއްގެ މިސާލަކީ، އެ ވައިރޯޅީގައި ގަދަ ފިނިކަމެއް (ނުވަތަ ގަދަ ހޫނުކަމެއް) ވާ، ވައިރޯޅިއެއް، އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް އަނިޔާކުޅަ ބަޔެއްގެ ދަނޑަށްޖެހި، އެ ދަނޑު ހަލާކުކޮށްލި ވައިރޯޅީގެ މިސާލެވެ. ﷲ، އެއުރެންނަކަށް އަނިޔާއެއް ނުކުރައްވަތެވެ. އެހެނެއްކަމަކު، އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް، އެއުރެން އަނިޔާކުރަނީއެވެ.","",""],["₃ سورة آل عمران","118","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تَتَّخِذُواْ بِطَانَةٗ مِّن دُونِكُمۡ لَا يَأۡلُونَكُمۡ خَبَالٗا وَدُّواْ مَا عَنِتُّمۡ قَدۡ بَدَتِ ٱلۡبَغۡضَآءُ مِنۡ أَفۡوَٰهِهِمۡ وَمَا تُخۡفِي صُدُورُهُمۡ أَكۡبَرُۚ قَدۡ بَيَّنَّا لَكُمُ ٱلۡأٓيَٰتِۖ إِن كُنتُمۡ تَعۡقِلُونَ ١١٨","يا أيها الذين آمنوا لا تتخذوا بطانة من دونكم لا يألونكم خبالا ودوا ما عنتم قد بدت البغضاء من أفواههم وما تخفي صدورهم أكبر قد بينا لكم الآيات إن كنتم تعقلون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ނޫން މީހުންގެ ތެރެއިން ގާތް އެކުވެރިން ތިޔަބައިމީހުން ނުހޯދާށެވެ! (އެހެނީ) ތިޔަބައިމީހުންގެ ކަންތައް ފަސާދަކުރުމުގައި، އެއުރެން ދުލެއް ނުދޭނެއެވެ. އެއުރެން އެދެނީ، ތިޔަބައިމީހުންނަށް ދަތިވެ އުނދަގޫވުމެވެ. ހަމަކަށަވަރުން، އެއުރެންގެ އަނގައިން ފާޅުވީ ރުޅިވެރިކަމެވެ. އަދި، އެއުރެންގެ ހިތްތަކުގައި ފޮރުވިފައިވާ ކަންތައް މާބޮޑެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށްޓަކައި، އާޔަތްތައް ބަޔާންކޮށް ދެއްވީމެވެ. ތިޔަބައިމީހުން ވިސްނާ ބަޔަކުކަމުގައި ވީނަމައެވެ.","",""],["₃ سورة آل عمران","119","هَـٰٓأَنتُمۡ أُوْلَآءِ تُحِبُّونَهُمۡ وَلَا يُحِبُّونَكُمۡ وَتُؤۡمِنُونَ بِٱلۡكِتَٰبِ كُلِّهِۦ وَإِذَا لَقُوكُمۡ قَالُوٓاْ ءَامَنَّا وَإِذَا خَلَوۡاْ عَضُّواْ عَلَيۡكُمُ ٱلۡأَنَامِلَ مِنَ ٱلۡغَيۡظِۚ قُلۡ مُوتُواْ بِغَيۡظِكُمۡۗ إِنَّ ٱللَّهَ عَلِيمُۢ بِذَاتِ ٱلصُّدُورِ ١١٩","ها أنتم أولاء تحبونهم ولا يحبونكم وتؤمنون بالكتاب كله وإذا لقوكم قالوا آمنا وإذا خلوا عضوا عليكم الأنامل من الغيظ قل موتوا بغيظكم إن الله عليم بذات الصدور","ތިޔަބައިމީހުން، އެއުރެންދެކެ ތިޔަ ލޯބިވަނީއެވެ. ތިޔަބައިމީހުން، ހުރިހައި ފޮތަކަށް އީމާން ވެގެން ތިބޭއިރުވެސް، އެއުރެން ތިޔަބައިމީހުންދެކެ ލޯތްބެއް ނުވެތެވެ. އަދި، އެއުރެން ތިޔަބައިމީހުންނާ ބައްދަލުވެއްޖެ ހިނދަކު، ތިމަންމެން އީމާން ވެއްޖައީމުއޭ ބުނެތެވެ. އަދި، އެއުރެން އެކަހެރިވެއްޖެނަމަ، ތިޔަބައިމީހުންދެކެ އަންނަ ރުޅިން އިނގިލިކުރިތަކުގައި ދައިގަނެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ރުޅިއައިސްގެން މަރުވާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ހިތްތަކުގައިވާހާ ކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","120","إِن تَمۡسَسۡكُمۡ حَسَنَةٞ تَسُؤۡهُمۡ وَإِن تُصِبۡكُمۡ سَيِّئَةٞ يَفۡرَحُواْ بِهَاۖ وَإِن تَصۡبِرُواْ وَتَتَّقُواْ لَا يَضُرُّكُمۡ كَيۡدُهُمۡ شَيۡـًٔاۗ إِنَّ ٱللَّهَ بِمَا يَعۡمَلُونَ مُحِيطٞ ١٢٠","إن تمسسكم حسنة تسؤهم وإن تصبكم سيئة يفرحوا بها وإن تصبروا وتتقوا لا يضركم كيدهم شيئا إن الله بما يعملون محيط","ތިޔަބައިމީހުންނަށް ހެޔޮގޮތެއް ދިމާވެއްޖެނަމަ، އެކަން އެއުރެންނަށް ހިތާމައަކަށްވެއެވެ. އަދި، ތިޔަބައިމީހުންނަށް ދެރަކަމެއް އައިސް ޖެހިއްޖެނަމަ އެކަމަށް އެއުރެން އުފާކުރެތެވެ. އަދި، ތިޔަބައިމީހުން ކެތްކޮށް ތަގުވާވެރިވާނަމަ، (އެބަހީ: ބިރުވެތިވެ ރައްކާތެރިވާނަމަ) އެއުރެންގެ މަކަރުވެރިކަމަކުން ތިޔަބައިމީހުންނަކަށް އެއްވެސް ގެއްލުމެއް ނުދެވޭނެއެވެ. ހަމަކަށަވަރުން، ﷲއީ، އެއުރެންކުރާ ޢަމަލުތައް ފުރިހަމަޔަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","121","وَإِذۡ غَدَوۡتَ مِنۡ أَهۡلِكَ تُبَوِّئُ ٱلۡمُؤۡمِنِينَ مَقَٰعِدَ لِلۡقِتَالِۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ ١٢١","وإذ غدوت من أهلك تبوئ المؤمنين مقاعد للقتال والله سميع عليم","(އުޙުދު ހަނގުރާމައިގެ ދުވަހު) ހަނގުރާމައިގެ މަރުކަޒުތަކަށް މުއުމިނުން ހަމަޖައްސަވައި ތައްޔާރުކުރެއްވުމަށްޓަކައި، ކަލޭގެފާނުންގެ އަހުލުވެރިންގެ ތެރެއިން ނުކުމެވަޑައިގެންނެވިހިނދު، (ހަނދުމަ ކުރައްވާށެވެ!) ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","122","إِذۡ هَمَّت طَّآئِفَتَانِ مِنكُمۡ أَن تَفۡشَلَا وَٱللَّهُ وَلِيُّهُمَاۗ وَعَلَى ٱللَّهِ فَلۡيَتَوَكَّلِ ٱلۡمُؤۡمِنُونَ ١٢٢","إذ همت طائفتان منكم أن تفشلا والله وليهما وعلى الله فليتوكل المؤمنون","(އެއީ) ތިޔަބައިމީހުންގެ ތެރެއިން ދެބަޔަކު ފިނޑިވެ، ހިތްވަރު އެލުނުހިނދެވެ. ﷲއީ، އެ ދެބައިމީހުން ރައްކާތެރިކުރައްވައި ނަސްރު ދެއްވާ ރަސްކަލާނގެއެވެ. ހަމައެކަނި ﷲއަށް މުއުމިނުން ވަކީލުކުރާހުށިކަމެވެ!","",""],["₃ سورة آل عمران","123","وَلَقَدۡ نَصَرَكُمُ ٱللَّهُ بِبَدۡرٖ وَأَنتُمۡ أَذِلَّةٞۖ فَٱتَّقُواْ ٱللَّهَ لَعَلَّكُمۡ تَشۡكُرُونَ ١٢٣","ولقد نصركم الله ببدر وأنتم أذلة فاتقوا الله لعلكم تشكرون","ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ނިކަމެތީން ކަމުގައިވަނިކޮށް، ބަދުރު ހަނގުރާމައިގައި ﷲ، ތިޔަބައިމީހުންނަށް ނަސްރު ދެއްވިއެވެ. ފަހެ، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! (އެއީ) ތިޔަބައިމީހުން ޝުކުރުވެރި ވުމަށްޓަކައެވެ.","",""],["₃ سورة آل عمران","124","إِذۡ تَقُولُ لِلۡمُؤۡمِنِينَ أَلَن يَكۡفِيَكُمۡ أَن يُمِدَّكُمۡ رَبُّكُم بِثَلَٰثَةِ ءَالَٰفٖ مِّنَ ٱلۡمَلَـٰٓئِكَةِ مُنزَلِينَ ١٢٤","إذ تقول للمؤمنين ألن يكفيكم أن يمدكم ربكم بثلاثة آلاف من الملائكة منزلين","(އެއީ) ކަލޭގެފާނު މުއުމިނުންނަށް ވިދާޅުވިހިނދުގައެވެ. ބާވައިލައްވާފައިވާ މަލާއިކަތުންގެ ތެރެއިން، ތިންހާހުން ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް މަދަދު ދެއްވުން ތިޔަބައިމީހުންނަކަށް ނުފުދޭހެއްޔެވެ؟","",""],["₃ سورة آل عمران","125","بَلَىٰٓۚ إِن تَصۡبِرُواْ وَتَتَّقُواْ وَيَأۡتُوكُم مِّن فَوۡرِهِمۡ هَٰذَا يُمۡدِدۡكُمۡ رَبُّكُم بِخَمۡسَةِ ءَالَٰفٖ مِّنَ ٱلۡمَلَـٰٓئِكَةِ مُسَوِّمِينَ ١٢٥","بلى إن تصبروا وتتقوا ويأتوكم من فورهم هذا يمددكم ربكم بخمسة آلاف من الملائكة مسومين","ނޫނެކެވެ! (ފުދޭނެއެވެ.) ތިޔަބައިމީހުން ކެތްތެރިވެ (ﷲއަށް) ބިރުވެތިވެ ރައްކާތެރިވާނަމަ، އަދި ތިޔަބައިމީހުންނާ ހަމަޔަށް އެއުރެން (އެބަހީ: މުޝްރިކުން) ހަމަ ކުއްލިޔަކަށް އަންނަނަމަ، ފާހަގަކުރައްވާފައިވާ ފަސްހާސް މަލާއިކަތުން (ފޮނުއްވައިގެން) ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް މަދަދު ދެއްވާނެތެވެ.","",""],["₃ سورة آل عمران","126","وَمَا جَعَلَهُ ٱللَّهُ إِلَّا بُشۡرَىٰ لَكُمۡ وَلِتَطۡمَئِنَّ قُلُوبُكُم بِهِۦۗ وَمَا ٱلنَّصۡرُ إِلَّا مِنۡ عِندِ ٱللَّهِ ٱلۡعَزِيزِ ٱلۡحَكِيمِ ١٢٦","وما جعله الله إلا بشرى لكم ولتطمئن قلوبكم به وما النصر إلا من عند الله العزيز الحكيم","އަދި، ތިޔަބައިމީހުންނަށް (ނަސްރު ލިބޭނެކަމުގެ) އުފާވެރި ޚަބަރެއް ކަމުގައްޔާއި، އަދި އެކަމުގެ ސަބަބުން ތިޔަބައިމީހުންގެ ހިތްތައް ހަމަޖެހުމަށްޓަކައި މެނުވީ، ﷲ އެކަންތަކެއް ނުލައްވަތެވެ. (އެބަހީ: މަލާއިކަތުން ފޮނުއްވައިގެން މަދަދު ދެއްވުން ނުލައްވަތެވެ.) ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ، ﷲގެ ހަޒުރަތުން މެނުވީ، ނަސްރު ލިބުމެއް ނުވެއެވެ.","",""],["₃ سورة آل عمران","127","لِيَقۡطَعَ طَرَفٗا مِّنَ ٱلَّذِينَ كَفَرُوٓاْ أَوۡ يَكۡبِتَهُمۡ فَيَنقَلِبُواْ خَآئِبِينَ ١٢٧","ليقطع طرفا من الذين كفروا أو يكبتهم فينقلبوا خائبين","(އެއީ) ކާފިރުވި މީހުންގެ ތެރެއިން ބަޔަކު، ނެތިކުރެއްވުމަށްޓަކައެވެ. ނުވަތަ، އެއުރެން ބަލިކުރައްވައި ނިކަމެތި ކުރެއްވުމަށްޓަކައެވެ. ފަހެ، (އެހިނދު) އެއުރެން ބޭނުންކަންތައް ނުވެ ހިތާމަކުރާ ޙާލު އެނބުރި ހިނގައިދެތެވެ.","",""],["₃ سورة آل عمران","128","لَيۡسَ لَكَ مِنَ ٱلۡأَمۡرِ شَيۡءٌ أَوۡ يَتُوبَ عَلَيۡهِمۡ أَوۡ يُعَذِّبَهُمۡ فَإِنَّهُمۡ ظَٰلِمُونَ ١٢٨","ليس لك من الأمر شيء أو يتوب عليهم أو يعذبهم فإنهم ظالمون","(އެއުރެންގެ) ކަންތަކުގެ ތެރެއިން އެއްވެސްކަމެއް، ކަލޭގެފާނަކަށް މިލްކުވެގެނެއް ނުވެއެވެ. (އެކަންއޮތީ ހަމައެކަނި ﷲއަށެވެ.) އެކަލާނގެ (އިރާދަކުރައްވާނަމަ) އެއުރެންގެ މައްޗަށް، ތައުބާ ލައްވައިފާނެތެވެ. ނުވަތަ، އެއުރެންނަށް އަޒާބު ދެއްވައިފާނެތެވެ. ފަހެ، ހަމަކަށަވަރުން، އެއުރެންނީ އަނިޔާވެރިންނެވެ.","",""],["₃ سورة آل عمران","129","وَلِلَّهِ مَا فِي ٱلسَّمَٰوَٰتِ وَمَا فِي ٱلۡأَرۡضِۚ يَغۡفِرُ لِمَن يَشَآءُ وَيُعَذِّبُ مَن يَشَآءُۚ وَٱللَّهُ غَفُورٞ رَّحِيمٞ ١٢٩","ولله ما في السماوات وما في الأرض يغفر لمن يشاء ويعذب من يشاء والله غفور رحيم","އުޑުތަކާއި، ބިމުގައި ވާހާ އެއްޗެއް މިލްކުވެގެންވަނީ، ﷲއަށެވެ. އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ފާފަފުއްސަވަތެވެ. އަދި، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް އަޒާބު ދެއްވަތެވެ. ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","130","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تَأۡكُلُواْ ٱلرِّبَوٰٓاْ أَضۡعَٰفٗا مُّضَٰعَفَةٗۖ وَٱتَّقُواْ ٱللَّهَ لَعَلَّكُمۡ تُفۡلِحُونَ ١٣٠","يا أيها الذين آمنوا لا تأكلوا الربا أضعافا مضاعفة واتقوا الله لعلكم تفلحون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ގިނަގުނަވެގެންވާ ގުނަތަކެއްގެ ގޮތުގައި ތިޔަބައިމީހުން ރިބާ ނުކާށެވެ! އަދި، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އެއީ، ތިޔަބައިމީހުން ދިންނަވައި ނަސީބު ލިބުމަށްޓަކައެވެ. (ނޯޓު: މި އާޔަތުގައި ގިނަގުނަވެގެންވާ ގުނަތަކެއްގެ ގޮތުގައި ރިބާ ނުކެއުމަށް އެންގެވުމަކުން، އެނޫންގޮތެއްގައި ރިބާ ކެއުން ހުއްދައެއް ނުވެއެވެ.)","",""],["₃ سورة آل عمران","131","وَٱتَّقُواْ ٱلنَّارَ ٱلَّتِيٓ أُعِدَّتۡ لِلۡكَٰفِرِينَ ١٣١","واتقوا النار التي أعدت للكافرين","އަދި، ނަރަކަޔަށް ތިޔަބައިމީހުން ބިރުވެތިވެ ރައްކާތެރިވާށެވެ! އެ ނަރަކަޔަކީ، ކާފިރުންނަށްޓަކައި ތައްޔާރުކުރައްވާފައިވާ ތަނެކެވެ.","",""],["₃ سورة آل عمران","132","وَأَطِيعُواْ ٱللَّهَ وَٱلرَّسُولَ لَعَلَّكُمۡ تُرۡحَمُونَ ١٣٢","وأطيعوا الله والرسول لعلكم ترحمون","އަދި، ﷲއަށާއި، ރަސޫލާއަށް، ތިޔަބައިމީހުން ކިޔަމަންތެރިވާށެވެ! (އެއީ) ތިޔަބައިމީހުންނަށް ރަހުމަތް ލެއްވުމަށްޓަކައެވެ.","",""],["₃ سورة آل عمران","133","۞وَسَارِعُوٓاْ إِلَىٰ مَغۡفِرَةٖ مِّن رَّبِّكُمۡ وَجَنَّةٍ عَرۡضُهَا ٱلسَّمَٰوَٰتُ وَٱلۡأَرۡضُ أُعِدَّتۡ لِلۡمُتَّقِينَ ١٣٣","وسارعوا إلى مغفرة من ربكم وجنة عرضها السماوات والأرض أعدت للمتقين","އަދި، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ފާފަފުއްސެވުން ލިބިގަތުމަށާއި، އުޑުތަކާއި ބިންފަދަ ތަނަވަސްކަންހުރި ސުވަރުގެޔަށް ތިޔަބައިމީހުން އަވަސްވެގަންނާށެވެ! އެ ސުވަރުގެ ތައްޔާރުކުރައްވާފައިވަނީ، ތަގުވާވެރިންނަށެވެ.","",""],["₃ سورة آل عمران","134","ٱلَّذِينَ يُنفِقُونَ فِي ٱلسَّرَّآءِ وَٱلضَّرَّآءِ وَٱلۡكَٰظِمِينَ ٱلۡغَيۡظَ وَٱلۡعَافِينَ عَنِ ٱلنَّاسِۗ وَٱللَّهُ يُحِبُّ ٱلۡمُحۡسِنِينَ ١٣٤","الذين ينفقون في السراء والضراء والكاظمين الغيظ والعافين عن الناس والله يحب المحسنين","އެއުރެންނަކީ، ތަނަވަސްކަމުގައްޔާއި، ދަތި ޙާލުގައި، (މުދާ) ހޭދަކޮށް އުޅޭމީހުންނެވެ. އަދި، ރުޅި މަތަކޮށް ހިފަހައްޓާ މީހުންނެވެ. އަދި، މީސްތަކުންނަށް މާފުކުރާ މީހުންނެވެ. އިހްސާން ތެރިންދެކެ ﷲ ލޯބިވެވޮޑިގެންވެއެވެ.","",""],["₃ سورة آل عمران","135","وَٱلَّذِينَ إِذَا فَعَلُواْ فَٰحِشَةً أَوۡ ظَلَمُوٓاْ أَنفُسَهُمۡ ذَكَرُواْ ٱللَّهَ فَٱسۡتَغۡفَرُواْ لِذُنُوبِهِمۡ وَمَن يَغۡفِرُ ٱلذُّنُوبَ إِلَّا ٱللَّهُ وَلَمۡ يُصِرُّواْ عَلَىٰ مَا فَعَلُواْ وَهُمۡ يَعۡلَمُونَ ١٣٥","والذين إذا فعلوا فاحشة أو ظلموا أنفسهم ذكروا الله فاستغفروا لذنوبهم ومن يغفر الذنوب إلا الله ولم يصروا على ما فعلوا وهم يعلمون","އަދި، އެއުރެންނީ ހުތުރުކަން ބޮޑުވެގެންވާ ފާފައެއްކޮށްފިނަމަ، ނުވަތަ، އެއުރެންގެ ނަފްސުތަކަށް އަނިޔާވެރިވެއްޖެނަމަ، (އެބަހީ: ކިތަންމެ ކުޑަނަމަވެސް ފާފައެއް ކޮށްފިނަމަ) ﷲ ހަނދުމަކޮށް، އެއުރެންގެ ފާފަތައް ފުއްސެވުންއެދި ދުއާ ކޮށް އުޅޭމީހުންނެވެ. ﷲ ފިޔަވައި ފާފަފުއްސަވާނީ ފަހެ، ކާކުހެއްޔެވެ؟ އަދި، އެއުރެން ދެނެތިބި ޙާލެއުރެން ކުޅަ ކުށުގެ މަތީގައި ދެމިއެއް ނުތިބެއެވެ.","",""],["₃ سورة آل عمران","136","أُوْلَـٰٓئِكَ جَزَآؤُهُم مَّغۡفِرَةٞ مِّن رَّبِّهِمۡ وَجَنَّـٰتٞ تَجۡرِي مِن تَحۡتِهَا ٱلۡأَنۡهَٰرُ خَٰلِدِينَ فِيهَاۚ وَنِعۡمَ أَجۡرُ ٱلۡعَٰمِلِينَ ١٣٦","أولئك جزاؤهم مغفرة من ربهم وجنات تجري من تحتها الأنهار خالدين فيها ونعم أجر العاملين","އެއުރެންގެ ޖަޒާޔަކީ އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ފާފަފުއްސެވުމެވެ. އަދި، އެތަންތާނގެ ދަށުން ކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކެވެ. އެތަންތާނގައި އެއުރެން ދެމިތިބޭ ޙާލު ގައެވެ. ހެޔޮ ޢަމަލުކުރާ މީހުންނަށް ހުރި ދަރުމައެއްގެ މޮޅުކަމާއެވެ!","",""],["₃ سورة آل عمران","137","قَدۡ خَلَتۡ مِن قَبۡلِكُمۡ سُنَنٞ فَسِيرُواْ فِي ٱلۡأَرۡضِ فَٱنظُرُواْ كَيۡفَ كَانَ عَٰقِبَةُ ٱلۡمُكَذِّبِينَ ١٣٧","قد خلت من قبلكم سنن فسيروا في الأرض فانظروا كيف كان عاقبة المكذبين","(އެކިއެކި އުއްމަތް ތަކާމެދު) ހިނގައިދިޔަ ކަންތައްތަކެއް ތިޔަބައިމީހުންގެ ކުރިން އިސްވެ ހިނގައްޖެކަން ކަށަވަރެވެ. ފަހެ، ތިޔަބައިމީހުން ބިމުގައި ދަތުރުފަތުރުކޮށް އުޅޭށެވެ! ދެން، ދޮގުކުޅަ މީހުންގެ ނަތީޖާއޮތީ ކޮންފަދަޔަކުންތޯ ނިކަން ބަލައިބަލާށެވެ!","",""],["₃ سورة آل عمران","138","هَٰذَا بَيَانٞ لِّلنَّاسِ وَهُدٗى وَمَوۡعِظَةٞ لِّلۡمُتَّقِينَ ١٣٨","هذا بيان للناس وهدى وموعظة للمتقين","މިއީ، މީސްތަކުންނަށް އޮތް ސާފުސީދާ ބަޔާނެކެވެ. އަދި، މަގު ދެއްކެވުމެކެވެ. އަދި، ތަގުވާވެރިންނަށްއޮތް ވައުޒެކެވެ.","",""],["₃ سورة آل عمران","139","وَلَا تَهِنُواْ وَلَا تَحۡزَنُواْ وَأَنتُمُ ٱلۡأَعۡلَوۡنَ إِن كُنتُم مُّؤۡمِنِينَ ١٣٩","ولا تهنوا ولا تحزنوا وأنتم الأعلون إن كنتم مؤمنين","ތިޔަބައިމީހުން (ފިނޑިވެ) ނިކަމެތި ނުވާށެވެ! އަދި، ތިޔަބައިމީހުން ހިތާމަވެސް ނުކުރާށެވެ! މަތިވެރިކަން ބޮޑުވެގެންވާ ބަޔަކީ ތިޔަބައިމީހުންނެވެ. (އެއީ) ތިޔަބައިމީހުން މުއުމިނުން ކަމުގައި ވާނަމައެވެ.","",""],["₃ سورة آل عمران","140","إِن يَمۡسَسۡكُمۡ قَرۡحٞ فَقَدۡ مَسَّ ٱلۡقَوۡمَ قَرۡحٞ مِّثۡلُهُۥۚ وَتِلۡكَ ٱلۡأَيَّامُ نُدَاوِلُهَا بَيۡنَ ٱلنَّاسِ وَلِيَعۡلَمَ ٱللَّهُ ٱلَّذِينَ ءَامَنُواْ وَيَتَّخِذَ مِنكُمۡ شُهَدَآءَۗ وَٱللَّهُ لَا يُحِبُّ ٱلظَّـٰلِمِينَ ١٤٠","إن يمسسكم قرح فقد مس القوم قرح مثله وتلك الأيام نداولها بين الناس وليعلم الله الذين آمنوا ويتخذ منكم شهداء والله لا يحب الظالمين","(އުޙުދު ހަނގުރާމައިގެ ދުވަހު) ތިޔަބައިމީހުންނަށް ހާނީއްކަޔާއި ވޭންލިބޭނަމަ، ހަމަކަށަވަރުން، (ކާފިރުންގެ) މީސްތަކުންނަށްވެސް، އެފަދަ ހާނީއްކަޔާއި ވޭން ވަނީ، (ބަދުރު ހަނގުރާމައިގެ ދުވަހުގައި) ލިބިފައެވެ. އެއީ، ދުވަސްތަކެކެވެ. ތިމަންރަސްކަލާނގެ އެދުވަސްތައް މީސްތަކުންގެ މެދުގައި އެކިގޮތްގޮތަށް ބަދަލުކުރައްވަމެވެ. އަދި، (އެއީ) އީމާން ވެއްޖެ މީސްތަކުން، ﷲ ދެނެވޮޑިގެންވެ، އެކަން ހާމަކުރެއްވުމަށްޓަކައްޔާއި، ތިޔަބައިމީހުންގެ ތެރެއިން ބަޔަކު ޝަހީދުން ކަމުގައި ލެއްވުމަށްޓަކައެވެ. އަނިޔާވެރިންދެކެ، ﷲ ލޯބިވެވޮޑިގެނެއްނުވެތެވެ.","",""],["₃ سورة آل عمران","141","وَلِيُمَحِّصَ ٱللَّهُ ٱلَّذِينَ ءَامَنُواْ وَيَمۡحَقَ ٱلۡكَٰفِرِينَ ١٤١","وليمحص الله الذين آمنوا ويمحق الكافرين","އަދި، ﷲ، އީމާން ވެއްޖެ މީސްތަކުން ތާހިރުކުރައްވައި، ސާފުކުރެއްވުމަށްޓަކައެވެ. އަދި، ކާފިރުން ހަލާކުކުރައްވައި، ނެތިކުރެއްވުމަށްޓަކައެވެ.","",""],["₃ سورة آل عمران","142","أَمۡ حَسِبۡتُمۡ أَن تَدۡخُلُواْ ٱلۡجَنَّةَ وَلَمَّا يَعۡلَمِ ٱللَّهُ ٱلَّذِينَ جَٰهَدُواْ مِنكُمۡ وَيَعۡلَمَ ٱلصَّـٰبِرِينَ ١٤٢","أم حسبتم أن تدخلوا الجنة ولما يعلم الله الذين جاهدوا منكم ويعلم الصابرين","ތިޔަބައިމީހުންގެ ތެރެއިން ޖިހާދުކުޅަމީހުން ﷲ ދެނެވޮޑިގެންވެ، އެކަން ހާމަނުވަނީސް އަދި، ކެތްތެރިންވެސް ދެނެވޮޑިގެންވެ، އެކަން ހާމަނުވަނީސް ތިޔަބައިމީހުން ސުވަރުގެ ވަންނާނެކަމަށް ތިޔަބައިމީހުން ހީކުރީހެއްޔެވެ؟","",""],["₃ سورة آل عمران","143","وَلَقَدۡ كُنتُمۡ تَمَنَّوۡنَ ٱلۡمَوۡتَ مِن قَبۡلِ أَن تَلۡقَوۡهُ فَقَدۡ رَأَيۡتُمُوهُ وَأَنتُمۡ تَنظُرُونَ ١٤٣","ولقد كنتم تمنون الموت من قبل أن تلقوه فقد رأيتموه وأنتم تنظرون","އަދި، މަރުވުމަށް އެދޭކަމުގައި (އެބަހީ: ޝަހީދު ވުމަށް އެދޭ ބަޔަކު ކަމުގައި) ހަމަކަށަވަރުންވެސް ތިޔަބައިމީހުން ވީމުއެވެ. (އެއީ) ތިޔަބައިމީހުން އެ މަރާ ބައްދަލުކުރުމުގެ ކުރީގައެވެ. ފަހެ، (މިހާރު) ތިޔަބައިމީހުން ލޮލުން ދެކޭ ޙާލުގައި ތިޔަބައިމީހުންނަށް އެކަންތައް ފެނިއްޖެކަން ކަށަވަރެވެ.","",""],["₃ سورة آل عمران","144","وَمَا مُحَمَّدٌ إِلَّا رَسُولٞ قَدۡ خَلَتۡ مِن قَبۡلِهِ ٱلرُّسُلُۚ أَفَإِيْن مَّاتَ أَوۡ قُتِلَ ٱنقَلَبۡتُمۡ عَلَىٰٓ أَعۡقَٰبِكُمۡۚ وَمَن يَنقَلِبۡ عَلَىٰ عَقِبَيۡهِ فَلَن يَضُرَّ ٱللَّهَ شَيۡـٔٗاۗ وَسَيَجۡزِي ٱللَّهُ ٱلشَّـٰكِرِينَ ١٤٤","وما محمد إلا رسول قد خلت من قبله الرسل أفإن مات أو قتل انقلبتم على أعقابكم ومن ينقلب على عقبيه فلن يضر الله شيئا وسيجزي الله الشاكرين","ރަސޫލަކު ކަމުގައި މެނުވީ މުޙައްމަދުގެފާނުން ނުވެއެވެ. ހަމަކަށަވަރުން، އެކަލޭގެފާނުންގެ ކުރިންވެސް ރަސޫލުން އިސްވެގޮސްފައިވެއެވެ. ފަހެ، އެކަލޭގެފާނު އަވަހާރަވެއްޖެނަމަ، ނުވަތަ ގަތުލު ވެއްޖެނަމަ، ތިޔަބައިމީހުން (ކާފިރު ވުމަށް) ފަހަތަށް އެނބުރި ގަންނަންވީ ހެއްޔެވެ؟ އަދި، ފަހަތަށް އެނބުރިގަންނަ މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް އެއްވެސް ކަމަކުން ﷲއަށް ގެއްލުމެއް ނުދެވޭނެތެވެ. ޝުކުރުކުރާ މީހުންނަށް ﷲ ޖަޒާ ދެއްވާނެތެވެ.","",""],["₃ سورة آل عمران","145","وَمَا كَانَ لِنَفۡسٍ أَن تَمُوتَ إِلَّا بِإِذۡنِ ٱللَّهِ كِتَٰبٗا مُّؤَجَّلٗاۗ وَمَن يُرِدۡ ثَوَابَ ٱلدُّنۡيَا نُؤۡتِهِۦ مِنۡهَا وَمَن يُرِدۡ ثَوَابَ ٱلۡأٓخِرَةِ نُؤۡتِهِۦ مِنۡهَاۚ وَسَنَجۡزِي ٱلشَّـٰكِرِينَ ١٤٥","وما كان لنفس أن تموت إلا بإذن الله كتابا مؤجلا ومن يرد ثواب الدنيا نؤته منها ومن يرد ثواب الآخرة نؤته منها وسنجزي الشاكرين","އަދި، ﷲގެ އިޒުނަ ފުޅާލައިގެންމެނުވީ، މަރުވުމަކީ، އެއްވެސް ނަފްސަކަށް އޮތްކަމެއް ނޫނެވެ. (އެކަންއޮތީ) ވަގުތު ކަނޑައަޅުއްވައި ލިޔުއްވާފައެވެ. އަދި، ދުނިޔޭގެ ސަވާބު އެދޭމީހާ، (ދަންނާށެވެ!) އެމީހަކަށް ތިމަންރަސްކަލާނގެ އޭގެތެރެއިން މިންވަރު ކުރައްވާފައިވާ އެއްޗެއް ދެއްވާހުށީމެވެ. އަދި، އާޚިރަތްގެ ސަވާބު އެދޭމީހާ، (ދަންނާށެވެ!) އެމީހަކަށް ތިމަންރަސްކަލާނގެ އޭގެތެރެއިން މިންވަރުކުރައްވާފައިވާ އެއްޗެއް ދެއްވާހުށީމެވެ. އަދި، ޝުކުރުކުރާ މީހުންނަށް ތިމަންރަސްކަލާނގެ ޖަޒާ ދެއްވާހުށީމެވެ.","",""],["₃ سورة آل عمران","146","وَكَأَيِّن مِّن نَّبِيّٖ قَٰتَلَ مَعَهُۥ رِبِّيُّونَ كَثِيرٞ فَمَا وَهَنُواْ لِمَآ أَصَابَهُمۡ فِي سَبِيلِ ٱللَّهِ وَمَا ضَعُفُواْ وَمَا ٱسۡتَكَانُواْۗ وَٱللَّهُ يُحِبُّ ٱلصَّـٰبِرِينَ ١٤٦","وكأين من نبي قاتل معه ربيون كثير فما وهنوا لما أصابهم في سبيل الله وما ضعفوا وما استكانوا والله يحب الصابرين","އެ ނަބިއްޔުންގެ އަރިހުގައި ގިނަވެގެންވާ ޖަމާއަތްތައް ހަނގުރާމަކުޅައީ ކިތައްކިތައް ނަބިއްޔުންހޭ؟ ފަހެ، ﷲގެ މަގުގައި އެއުރެންނަށް ޖެހުނު ކަންތަކަށް އެއުރެން ފިނޑިއެއްނުވިއެވެ. އަދި، އެއުރެން ނިކަމެއްޗެއްވެސް ނުވިއެވެ. އަދި، (ދުޝްމަނުންގެ ކުރިމަތީގައި) އެއުރެން ބަލިކަށްޓެއްވެސް ނުވިއެވެ. ކެތްތެރިންދެކެ ﷲ ލޯބިވެވޮޑިގެންވެތެވެ.","",""],["₃ سورة آل عمران","147","وَمَا كَانَ قَوۡلَهُمۡ إِلَّآ أَن قَالُواْ رَبَّنَا ٱغۡفِرۡ لَنَا ذُنُوبَنَا وَإِسۡرَافَنَا فِيٓ أَمۡرِنَا وَثَبِّتۡ أَقۡدَامَنَا وَٱنصُرۡنَا عَلَى ٱلۡقَوۡمِ ٱلۡكَٰفِرِينَ ١٤٧","وما كان قولهم إلا أن قالوا ربنا اغفر لنا ذنوبنا وإسرافنا في أمرنا وثبت أقدامنا وانصرنا على القوم الكافرين","އަދި، އެއުރެންގެ ބަހެއްކަމުގައި އެއުރެން ދެންނެވުންމެނުވީ ނުވެއެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! އަޅަމެންގެ ފާފަތަކާއި، އަޅަމެންގެ ކަންތަކުގައި ހައްދުފަހަނަޅައިދިއުމުގެ ކުށް އަޅަމެންނަށް ފުއްސަވާނދޭވެ! އަދި، އަޅަމެންގެ ފައިތިލަތައް ސާބިތުކުރައްވާނދޭވެ! އަދި، ކާފިރު ވެގެންވާ ގައުމުގެ މައްޗަށް އަޅަމެންނަށް ނަސްރު ދެއްވާނދޭވެ!","",""],["₃ سورة آل عمران","148","فَـَٔاتَىٰهُمُ ٱللَّهُ ثَوَابَ ٱلدُّنۡيَا وَحُسۡنَ ثَوَابِ ٱلۡأٓخِرَةِۗ وَٱللَّهُ يُحِبُّ ٱلۡمُحۡسِنِينَ ١٤٨","فآتاهم الله ثواب الدنيا وحسن ثواب الآخرة والله يحب المحسنين","ދެންފަހެ، ދުނިޔޭގެ ސަވާބާއި، އާޚިރަތްގެ ރިވެތި ސަވާބެއުރެންނަށް ﷲ ދެއްވިއެވެ. އިހްސާން ތެރިންދެކެ ﷲ ލޯބިވެވޮޑިގެންވެތެވެ.","",""],["₃ سورة آل عمران","149","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ إِن تُطِيعُواْ ٱلَّذِينَ كَفَرُواْ يَرُدُّوكُمۡ عَلَىٰٓ أَعۡقَٰبِكُمۡ فَتَنقَلِبُواْ خَٰسِرِينَ ١٤٩","يا أيها الذين آمنوا إن تطيعوا الذين كفروا يردوكم على أعقابكم فتنقلبوا خاسرين","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ކާފިރުވި މީހުންނަށް ތިޔަބައިމީހުން ކިޔަމަންވާނަމަ، ތިޔަބައިމީހުންގެ ފުރަގަހަށް އެއުރެން ތިޔަބައިމީހުން އަނބުރާ ރައްދުކޮށްފާނެތެވެ. (އެބަހީ: ތިޔަބައިމީހުން ދީނުން ބޭރުކޮށްފާނެތެވެ.) ފަހެ، (އެހިނދު) ތިޔަބައިމީހުން އެނބުރިދާނީ، ގެއްލެނިވެގެންވާ ޙާލު ގައެވެ.","",""],["₃ سورة آل عمران","150","بَلِ ٱللَّهُ مَوۡلَىٰكُمۡۖ وَهُوَ خَيۡرُ ٱلنَّـٰصِرِينَ ١٥٠","بل الله مولاكم وهو خير الناصرين","އަދި، ކިއެއްތަ! ތިޔަބައިމީހުންނަށް ނަސްރު ދެއްވާ އެހީތެރިޔަކީ ﷲއެވެ. އަދި، ނަސްރު ދެއްވާ އެންމެ ހެޔޮފަރާތަކީ އެކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","151","سَنُلۡقِي فِي قُلُوبِ ٱلَّذِينَ كَفَرُواْ ٱلرُّعۡبَ بِمَآ أَشۡرَكُواْ بِٱللَّهِ مَا لَمۡ يُنَزِّلۡ بِهِۦ سُلۡطَٰنٗاۖ وَمَأۡوَىٰهُمُ ٱلنَّارُۖ وَبِئۡسَ مَثۡوَى ٱلظَّـٰلِمِينَ ١٥١","سنلقي في قلوب الذين كفروا الرعب بما أشركوا بالله ما لم ينزل به سلطانا ومأواهم النار وبئس مثوى الظالمين","ކާފިރުވި މީހުންގެ ހިތްތަކަށް ނިކަންހުރެ ތިމަންރަސްކަލާނގެ ބިރުވެރިކަން ވައްދަވާހުށީމެވެ. (އެއީ) އެތަކެއްޗަށް ﷲއެއްވެސް ބާރެއް ބާވައިލައްވާފައިނުވާ ތަކެތި، ﷲއާ އެއްފަދަކޮށް، އެއުރެން ޝަރީކުކުޅަކަމަށްޓަކައެވެ. އަދި، އެއުރެން ތިބެނިވި ތަނަކީ، ނަރަކަޔެވެ. އެއީ، އަނިޔާވެރިން (އެބަހީ: މުޝްރިކުން) ތިބުމަށް ހާދަހާ ނުބައި ތަނެކެވެ.","",""],["₃ سورة آل عمران","152","وَلَقَدۡ صَدَقَكُمُ ٱللَّهُ وَعۡدَهُۥٓ إِذۡ تَحُسُّونَهُم بِإِذۡنِهِۦۖ حَتَّىٰٓ إِذَا فَشِلۡتُمۡ وَتَنَٰزَعۡتُمۡ فِي ٱلۡأَمۡرِ وَعَصَيۡتُم مِّنۢ بَعۡدِ مَآ أَرَىٰكُم مَّا تُحِبُّونَۚ مِنكُم مَّن يُرِيدُ ٱلدُّنۡيَا وَمِنكُم مَّن يُرِيدُ ٱلۡأٓخِرَةَۚ ثُمَّ صَرَفَكُمۡ عَنۡهُمۡ لِيَبۡتَلِيَكُمۡۖ وَلَقَدۡ عَفَا عَنكُمۡۗ وَٱللَّهُ ذُو فَضۡلٍ عَلَى ٱلۡمُؤۡمِنِينَ ١٥٢","ولقد صدقكم الله وعده إذ تحسونهم بإذنه حتى إذا فشلتم وتنازعتم في الأمر وعصيتم من بعد ما أراكم ما تحبون منكم من يريد الدنيا ومنكم من يريد الآخرة ثم صرفكم عنهم ليبتليكم ولقد عفا عنكم والله ذو فضل على المؤمنين","ހަމަކަށަވަރުން ﷲ، ތިޔަބައިމީހުންނަށް، އެކަލާނގެ ވައުދުފުޅު ފުއްދަވައި ދެއްވިއެވެ. އެކަލާނގެ އިޒުނަ ފުޅާލައިގެން ތިޔަބައިމީހުން އެ ކާފިރުން ގަތުލު ކޮށް ނެތިކުރަމުން ދިޔަހިނދުގައެވެ. ތިޔަބައިމީހުން ހިތްއެދޭ ކަންތައް ތިޔަބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ ދެއްކެވުމަށްފަހު، ތިޔަބައިމީހުން އުރެދި، އަދި (ރަސޫލާ އެންގެވި) ކަންތަކުގައި ތިޔަބައިމީހުން ދެބަސްވެ، ފިނޑިވެއްޖައުމަށް ދާނދެނެވެ. ތިޔަބައިމީހުންގެ ތެރޭގައި ދުނިޔެ އެދޭ މީހުންވެއެވެ. އަދި، ތިޔަބައިމީހުންގެ ތެރޭގައި އާޚިރަތް އެދޭމީހުންވެސްވެއެވެ. ދެން، އެ ކާފިރުންގެ ކިބައިން ތިޔަބައިމީހުން އެއްކިބާ ކުރެއްވިއެވެ. އެއީ، ތިޔަބައިމީހުން އިމްތިހާނުކުރެއްވުމަށްޓަކައެވެ. އަދި، ހަމަކަށަވަރުން އެކަލާނގެ ތިޔަބައިމީހުންނަށް އަފޫކުރެއްވިއެވެ. ﷲއީ، މުއުމިނު ތަކުންގެ މައްޗަށް ފަޟްލު ވަންތަވެރި ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","153","۞إِذۡ تُصۡعِدُونَ وَلَا تَلۡوُۥنَ عَلَىٰٓ أَحَدٖ وَٱلرَّسُولُ يَدۡعُوكُمۡ فِيٓ أُخۡرَىٰكُمۡ فَأَثَٰبَكُمۡ غَمَّۢا بِغَمّٖ لِّكَيۡلَا تَحۡزَنُواْ عَلَىٰ مَا فَاتَكُمۡ وَلَا مَآ أَصَٰبَكُمۡۗ وَٱللَّهُ خَبِيرُۢ بِمَا تَعۡمَلُونَ ١٥٣","إذ تصعدون ولا تلوون على أحد والرسول يدعوكم في أخراكم فأثابكم غما بغم لكيلا تحزنوا على ما فاتكم ولا ما أصابكم والله خبير بما تعملون","(އެއީ) ތިޔަބައިމީހުން އެކަކަށްވެސް އެނބުރި ބަލައިނުލައި ދުރަށްދިޔަ ހިނދުގައެވެ. ތިޔަބައިމީހުންގެ ފަހަތުން ރަސޫލާ ތިޔަބައިމީހުންނަށް ގޮވާލައްވާ ޙާލު ގައެވެ. ދެން، މޮޅިވެރިކަމަކާ ވިދިގެން މޮޅިވެރިކަމަކުން ތިޔަބައިމީހުންނަށް ޖަޒާ ދެއްވިއެވެ. (އެއީ) ތިޔަބައިމީހުންނަށް (ޣަނީމާ އިން) ފާއިތުވީ އެއްޗެއްގެ މައްޗަށާއި، ތިޔަބައިމީހުންނަށް ޖެހުނު ކަންތަކުގެ މައްޗަށް ތިޔަބައިމީހުން ހިތާމަ ނުކުރުމަށްޓަކައެވެ. ﷲއީ، ތިޔަބައިމީހުން ކުރާ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","154","ثُمَّ أَنزَلَ عَلَيۡكُم مِّنۢ بَعۡدِ ٱلۡغَمِّ أَمَنَةٗ نُّعَاسٗا يَغۡشَىٰ طَآئِفَةٗ مِّنكُمۡۖ وَطَآئِفَةٞ قَدۡ أَهَمَّتۡهُمۡ أَنفُسُهُمۡ يَظُنُّونَ بِٱللَّهِ غَيۡرَ ٱلۡحَقِّ ظَنَّ ٱلۡجَٰهِلِيَّةِۖ يَقُولُونَ هَل لَّنَا مِنَ ٱلۡأَمۡرِ مِن شَيۡءٖۗ قُلۡ إِنَّ ٱلۡأَمۡرَ كُلَّهُۥ لِلَّهِۗ يُخۡفُونَ فِيٓ أَنفُسِهِم مَّا لَا يُبۡدُونَ لَكَۖ يَقُولُونَ لَوۡ كَانَ لَنَا مِنَ ٱلۡأَمۡرِ شَيۡءٞ مَّا قُتِلۡنَا هَٰهُنَاۗ قُل لَّوۡ كُنتُمۡ فِي بُيُوتِكُمۡ لَبَرَزَ ٱلَّذِينَ كُتِبَ عَلَيۡهِمُ ٱلۡقَتۡلُ إِلَىٰ مَضَاجِعِهِمۡۖ وَلِيَبۡتَلِيَ ٱللَّهُ مَا فِي صُدُورِكُمۡ وَلِيُمَحِّصَ مَا فِي قُلُوبِكُمۡۚ وَٱللَّهُ عَلِيمُۢ بِذَاتِ ٱلصُّدُورِ ١٥٤","ثم أنزل عليكم من بعد الغم أمنة نعاسا يغشى طائفة منكم وطائفة قد أهمتهم أنفسهم يظنون بالله غير الحق ظن الجاهلية يقولون هل لنا من الأمر من شيء قل إن الأمر كله لله يخفون في أنفسهم ما لا يبدون لك يقولون لو كان لنا من الأمر شيء ما قتلنا هاهنا قل لو كنتم في بيوتكم لبرز الذين كتب عليهم القتل إلى مضاجعهم وليبتلي الله ما في صدوركم وليمحص ما في قلوبكم والله عليم بذات الصدور","ދެން، އެ ހިތާމަޔަށްފަހު ތިޔަބައިމީހުންގެ ތެރެއިން ބަޔަކަށްޖެހޭ މަޑު ނިންޖެއްގެ ގޮތުގައި، ތިޔަބައިމީހުންގެ މައްޗަށް އެކަލާނގެ އަމާންކަން ބާވައިލެއްވިއެވެ. އަނެއްބަޔަކަށް އެއުރެންގެ އަމިއްލަ ނަފްސު ތަކުން ހިތާމަވެރިކަން ލިއްބައިފިކަން ކަށަވަރެވެ. ﷲއާމެދު އެއުރެން ހައްގު ނޫންގޮތްތައް ހީކުރެތެވެ. (އެއީ) ޖާހިލީ ޒަމާނުގެ ހީކުރުމެވެ. އެއުރެން ބުނެތެވެ. ކަންތަކުގެ ތެރެއިން (އެބަހީ: ނަސްރު ދެއްވުންފަދަ ކަންތަކުގެ ތެރެއިން) އެއްވެސްކަމެއް ތިމަންމެންނަށް ވޭތޯއެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ހުރިހާކަމެއްމެ މިލްކުވެގެންވަނީ ﷲއަށެވެ. ކަލޭގެފާނަށް އެއުރެން ފާޅުނުކުރާ ކަންތައް، އެއުރެންގެ ހިތްތަކުގައި ވަންހަނާ ކުރެތެވެ. އެއުރެން ބުނެތެވެ. ކަންތަކުގެ ތެރެއިން ކަމެއް (އެބަހީ: ހަނގުރާމަޔަށް ނުކުތުމާމެދު އިޚްތިޔާރެއް) ތިމަންމެންނަށް ލިބިގެންވީނަމަ، މިތާނގައި ތިމަންމެން ގަތުލެއް ނުވީހެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންގެ ގޭގޭގައި ތިޔަބައިމީހުން ވީކަމުގައިވިޔަސް ގަތުލު ވުން އެބަޔެއްގެ މައްޗަށް ކަނޑައަޅުއްވައި ލިޔުއްވާފައިވާ މީހުން، އެއުރެން ގަތުލު ވެގެން ވެއްޓޭނޭ ތަންތަނަށް ނުކުތީސްކަން ކަށަވަރެވެ. އަދި، (ތިޔަބައިމީހުންގެ މައްޗަށް ހަނގުރާމަ ފަރުޟުކުރެއްވީ) ﷲ ތިޔަބައިމީހުންގެ ހިތްތަކުގައިވާގޮތް އިމްތިހާނުކުރެއްވުމަށްޓަކައެވެ. އަދި، ތިޔަބައިމީހުންގެ ހިތްތަކުގައިވާ ގޮތްތައް ވަކި ކުރައްވައި ހާމަކުރެއްވުމަށްޓަކައެވެ. ﷲއީ، ހިތްތަކުގައި ވާހައިކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","155","إِنَّ ٱلَّذِينَ تَوَلَّوۡاْ مِنكُمۡ يَوۡمَ ٱلۡتَقَى ٱلۡجَمۡعَانِ إِنَّمَا ٱسۡتَزَلَّهُمُ ٱلشَّيۡطَٰنُ بِبَعۡضِ مَا كَسَبُواْۖ وَلَقَدۡ عَفَا ٱللَّهُ عَنۡهُمۡۗ إِنَّ ٱللَّهَ غَفُورٌ حَلِيمٞ ١٥٥","إن الذين تولوا منكم يوم التقى الجمعان إنما استزلهم الشيطان ببعض ما كسبوا ولقد عفا الله عنهم إن الله غفور حليم","ހަމަކަށަވަރުން، (އުޙުދު ހަނގުރާމައިގައި) ދެ ލަޝްކަރު ބައްދަލުވީ ދުވަހު، ތިޔަބައިމީހުންގެ ތެރެއިން (ހަނގުރާމަޔަށް) އެނބުރި ފުރަގަސްދިން މީހުން، ޝައިތާނާ އެއުރެންގެ މަގުން އެއްކިބާ ކުރިކަން ކަށަވަރީ، އެއުރެން ހޯދި ބައެއް ކަންތަކުގެ ސަބަބުންނެވެ. (އެބަހީ: ރަސޫލާގެ އެންގެވުންތަކާ ޚިލާފު ވުމުގެ ސަބަބުންނެވެ.) ހަމަކަށަވަރުން، ﷲއެއުރެންނަށް އަފޫކުރައްވައިފިއެވެ. ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ހަލީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","156","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تَكُونُواْ كَٱلَّذِينَ كَفَرُواْ وَقَالُواْ لِإِخۡوَٰنِهِمۡ إِذَا ضَرَبُواْ فِي ٱلۡأَرۡضِ أَوۡ كَانُواْ غُزّٗى لَّوۡ كَانُواْ عِندَنَا مَا مَاتُواْ وَمَا قُتِلُواْ لِيَجۡعَلَ ٱللَّهُ ذَٰلِكَ حَسۡرَةٗ فِي قُلُوبِهِمۡۗ وَٱللَّهُ يُحۡيِۦ وَيُمِيتُۗ وَٱللَّهُ بِمَا تَعۡمَلُونَ بَصِيرٞ ١٥٦","يا أيها الذين آمنوا لا تكونوا كالذين كفروا وقالوا لإخوانهم إذا ضربوا في الأرض أو كانوا غزى لو كانوا عندنا ما ماتوا وما قتلوا ليجعل الله ذلك حسرة في قلوبهم والله يحيي ويميت والله بما تعملون بصير","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ކާފިރުވި މީހުން ފަދައިން ތިޔަބައިމީހުން ނުވާށެވެ! (އެއީ) އެއުރެންގެ އަޚުން ދަތުރު ފަތުރުކޮށް އުޅުނުހިނދު ނުވަތަ، ހަނގުރާމަވެރިންކަމުގައި ވީހިނދު، ތިމަންމެންގެ ގާތުގައި އެއުރެން ތިބިނަމަ މަރެއްނުވީހޭ، އަދި ގަތުލެއްވެސް ނުވީހޭ، އެއުރެންގެ އަޚުންނަށް ބުނި މީހުންނެވެ. (އެއުރެން އެ ބަސްބުނީ) ﷲ، އެ ބަސް އެއުރެންގެ ހިތްތަކުގައި ހިތާމަޔެއް ކަމުގައި ލެއްވުމަށެވެ. ދިރުއްވަނީވެސް، އަދި މަރުގަންނަވަނީވެސް، ﷲއެވެ. އަދި، ﷲއީ، ތިޔަބައިމީހުން ކުރާ ކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","157","وَلَئِن قُتِلۡتُمۡ فِي سَبِيلِ ٱللَّهِ أَوۡ مُتُّمۡ لَمَغۡفِرَةٞ مِّنَ ٱللَّهِ وَرَحۡمَةٌ خَيۡرٞ مِّمَّا يَجۡمَعُونَ ١٥٧","ولئن قتلتم في سبيل الله أو متم لمغفرة من الله ورحمة خير مما يجمعون","ހަމަކަށަވަރުން، ﷲގެ މަގުގައި ތިޔަބައިމީހުން ގަތުލު ވިޔަސް، ނުވަތަ މަރުވިޔަސް، ﷲގެ ހަޒުރަތުން ފާފަފުއްސެވުމާއި، ރަހުމަތް ލެއްވުން އެއުރެން އެއްކުރާ ތަކެއްޗަށްވުރެ މާ ހެޔޮކަން ބޮޑެވެ.","",""],["₃ سورة آل عمران","158","وَلَئِن مُّتُّمۡ أَوۡ قُتِلۡتُمۡ لَإِلَى ٱللَّهِ تُحۡشَرُونَ ١٥٨","ولئن متم أو قتلتم لإلى الله تحشرون","ހަމަކަށަވަރުން، ތިޔަބައިމީހުން މަރުވިޔަސް، ނުވަތަ ގަތުލު ވިޔަސް، ތިޔަބައިމީހުން އެއްކުރައްވާހުށީ، ﷲގެ ހަޒުރަތަށް ކަން ކަށަވަރެވެ.","",""],["₃ سورة آل عمران","159","فَبِمَا رَحۡمَةٖ مِّنَ ٱللَّهِ لِنتَ لَهُمۡۖ وَلَوۡ كُنتَ فَظًّا غَلِيظَ ٱلۡقَلۡبِ لَٱنفَضُّواْ مِنۡ حَوۡلِكَۖ فَٱعۡفُ عَنۡهُمۡ وَٱسۡتَغۡفِرۡ لَهُمۡ وَشَاوِرۡهُمۡ فِي ٱلۡأَمۡرِۖ فَإِذَا عَزَمۡتَ فَتَوَكَّلۡ عَلَى ٱللَّهِۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلۡمُتَوَكِّلِينَ ١٥٩","فبما رحمة من الله لنت لهم ولو كنت فظا غليظ القلب لانفضوا من حولك فاعف عنهم واستغفر لهم وشاورهم في الأمر فإذا عزمت فتوكل على الله إن الله يحب المتوكلين","އެއުރެންނަށް ކަލޭގެފާނު އޯގާވެރިވެވަޑައިގަތީ، ﷲގެ ހަޒުރަތުން ލެއްވި ރަހުމަތެއްގެ ސަބަބުންނެވެ. ހިތްޕުޅު ހަރުކަށި، ޚުލުގު ނުބައި ބޭކަލަކު ކަމުގައި ކަލޭގެފާނުވިނަމަ، ކަލޭގެފާނުގެ އަރިހުން އެއުރެން ވަކިވެގެން ހިނގައްޖައީހެވެ. ފަހެ، އެއުރެންނަށް ކަލޭގެފާނު އަފޫކުރައްވާށެވެ! އަދި، އެއުރެންނަށް ފާފަފުއްސެވުން އެދި ދަންނަވާށެވެ! އަދި، ކަންތަކުގައި ކަލޭގެފާނު އެމީހުންނާ މަޝްވަރާކުރައްވާށެވެ! ފަހެ، (ކަމަކާމެދު) ކަލޭގެފާނު ޢަޒުމު ކަނޑައަޅުއްވައިފިނަމަ، ފަހެ، ކަލޭގެފާނު ﷲއަށް ވަކީލުކުރައްވާށެވެ! ހަމަކަށަވަރުން، ވަކީލުކުރާ މީހުންދެކެ ﷲ ލޯބިވެވޮޑިގެންވެތެވެ.","",""],["₃ سورة آل عمران","160","إِن يَنصُرۡكُمُ ٱللَّهُ فَلَا غَالِبَ لَكُمۡۖ وَإِن يَخۡذُلۡكُمۡ فَمَن ذَا ٱلَّذِي يَنصُرُكُم مِّنۢ بَعۡدِهِۦۗ وَعَلَى ٱللَّهِ فَلۡيَتَوَكَّلِ ٱلۡمُؤۡمِنُونَ ١٦٠","إن ينصركم الله فلا غالب لكم وإن يخذلكم فمن ذا الذي ينصركم من بعده وعلى الله فليتوكل المؤمنون","ﷲ، ތިޔަބައިމީހުންނަށް ނަސްރު ދެއްވާނަމަ، ފަހެ، ތިޔަބައިމީހުން ބަލިކުރާނޭ އެއްވެސް ފަރާތެއްނެތެވެ. އަދި، އެކަލާނގެ ތިޔަބައިމީހުން ދެރަކުރައްވާނަމަ، އެއަށްފަހު ތިޔަބައިމީހުންނަށް ނަސްރު ދޭނީ ފަހެ، ކާކުހެއްޔެވެ؟ އަދި، ހަމައެކަނި ﷲއަށް މުއުމިނުން ވަކީލުކުރާހުށިކަމެވެ!","",""],["₃ سورة آل عمران","161","وَمَا كَانَ لِنَبِيٍّ أَن يَغُلَّۚ وَمَن يَغۡلُلۡ يَأۡتِ بِمَا غَلَّ يَوۡمَ ٱلۡقِيَٰمَةِۚ ثُمَّ تُوَفَّىٰ كُلُّ نَفۡسٖ مَّا كَسَبَتۡ وَهُمۡ لَا يُظۡلَمُونَ ١٦١","وما كان لنبي أن يغل ومن يغلل يأت بما غل يوم القيامة ثم توفى كل نفس ما كسبت وهم لا يظلمون","(ޣަނީމާ) މުދަލަށް ޚިޔާނަތް ތެރިވުމަކީ، ނަބީބޭކަލަކަށް އޮތްކަމެއް ނޫނެވެ. އަދި، މުދަލަށް ޚިޔާނަތް ތެރިވާ މީހާ އެމީހަކު ޚިޔާނަތް ތެރިވި ތަކެއްޗާއިގެން ގިޔާމަތް ދުވަހުން (އެކަލާނގެ ހަޒުރަތަށް) އަންނާނެތެވެ. ދެން، ކޮންމެ ނަފްސަކަށްމެ އެ ނަފްސެއް ހޯދިކަމެއް (ގެ ޖަޒާ) ފުރިހަމަޔަށް ލިބިދެއްވާނެތެވެ. އެއުރެންނަށް ބޭއިންސާފު ނުކުރައްވާ ގޮތުގައެވެ.","",""],["₃ سورة آل عمران","162","أَفَمَنِ ٱتَّبَعَ رِضۡوَٰنَ ٱللَّهِ كَمَنۢ بَآءَ بِسَخَطٖ مِّنَ ٱللَّهِ وَمَأۡوَىٰهُ جَهَنَّمُۖ وَبِئۡسَ ٱلۡمَصِيرُ ١٦٢","أفمن اتبع رضوان الله كمن باء بسخط من الله ومأواه جهنم وبئس المصير","ފަހެ، ﷲގެ ރުއްސެވުމަށް ތަބާ ވީމީހާ، ﷲގެ ހަޒުރަތުން އަންނަ ކޯފާއަކާއިގެން އެނބުރި އައިމީހެއްފަދަ ހެއްޔެވެ؟ އަދި، އެމީހަކު (އެބަހީ: ﷲގެ ކޯފާއާއިގެން އައި މީހަކު) އުޅޭނެތަނަކީ، ޖަހައްނަމެވެ. (އެއީ) ހާދަހާ ނުބައިވެގެންވާ ނިމިދިއުމެކެވެ.","",""],["₃ سورة آل عمران","163","هُمۡ دَرَجَٰتٌ عِندَ ٱللَّهِۗ وَٱللَّهُ بَصِيرُۢ بِمَا يَعۡمَلُونَ ١٦٣","هم درجات عند الله والله بصير بما يعملون","އެއުރެން، ﷲގެ ހަޒުރަތުގައި ވަނީ ދަރަޖަތަކަކަށެވެ. އަދި، ﷲއީ، އެއުރެންކުރާ ކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","164","لَقَدۡ مَنَّ ٱللَّهُ عَلَى ٱلۡمُؤۡمِنِينَ إِذۡ بَعَثَ فِيهِمۡ رَسُولٗا مِّنۡ أَنفُسِهِمۡ يَتۡلُواْ عَلَيۡهِمۡ ءَايَٰتِهِۦ وَيُزَكِّيهِمۡ وَيُعَلِّمُهُمُ ٱلۡكِتَٰبَ وَٱلۡحِكۡمَةَ وَإِن كَانُواْ مِن قَبۡلُ لَفِي ضَلَٰلٖ مُّبِينٍ ١٦٤","لقد من الله على المؤمنين إذ بعث فيهم رسولا من أنفسهم يتلو عليهم آياته ويزكيهم ويعلمهم الكتاب والحكمة وإن كانوا من قبل لفي ضلال مبين","ހަމަކަށަވަރުން، މުއުމިނުންގެ މައްޗަށް ﷲ ދަރުމަވަންތަވެ ވޮޑިގެންފިއެވެ. (އެއީ) އެއުރެންގެ ތެރެޔަށް، ހަމަ އެއުރެންގެ ތެރެއިން ރަސޫލަކު ފޮނުއްވި ހިނދުގައެވެ. އެކަލާނގެ އާޔަތްތައް އެއުރެންނަށް ކިޔަވައިދެއްވާ އަދި، އެއުރެން ތާހިރުކުރައްވާ، އަދި ފޮތާއި ހިކުމަތް، އެއުރެންނަށް އުނގަންނައިދެއްވާ ބޭކަލެއްގެ ގޮތުގައެވެ. އޭގެކުރިން އެއުރެންވީ، ބަޔާންވެގެންވާ މަގުފުރެދުމެއްގައިކަން ކަށަވަރެވެ.","",""],["₃ سورة آل عمران","165","أَوَلَمَّآ أَصَٰبَتۡكُم مُّصِيبَةٞ قَدۡ أَصَبۡتُم مِّثۡلَيۡهَا قُلۡتُمۡ أَنَّىٰ هَٰذَاۖ قُلۡ هُوَ مِنۡ عِندِ أَنفُسِكُمۡۗ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٞ ١٦٥","أولما أصابتكم مصيبة قد أصبتم مثليها قلتم أنى هذا قل هو من عند أنفسكم إن الله على كل شيء قدير","މިކަންތައްއައީ ކޮންތާކުންހޭ ތިޔަބައިމީހުން ބުނީ، ތިޔަބައިމީހުންނަށް މުސީބަތެއް އައިސް ޖެހުނީމާ ހެއްޔެވެ؟ ހަމަކަށަވަރުން، އެ މުސީބަތްގެ ދެގުނަ (އެއުރެންނަށް) ތިޔަބައިމީހުންވަނީ ޖައްސާފައެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއީ، ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުގެ ފަރާތުން އައިކަމެކެވެ. ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެ ކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","166","وَمَآ أَصَٰبَكُمۡ يَوۡمَ ٱلۡتَقَى ٱلۡجَمۡعَانِ فَبِإِذۡنِ ٱللَّهِ وَلِيَعۡلَمَ ٱلۡمُؤۡمِنِينَ ١٦٦","وما أصابكم يوم التقى الجمعان فبإذن الله وليعلم المؤمنين","(އުޙުދު ހަނގުރާމައިގައި) ދެ ލަޝްކަރު ބައްދަލުވި ދުވަހު، ތިޔަބައިމީހުންނަށް ޖެހުނުކަންތައް (ދަންނާށެވެ!) ފަހެ، އެއީ ﷲގެ އިޒުނަ ފުޅާ ލައިގެން ޖެހުނުކަމެކެވެ. އަދި، (ތެދުވެރި) މުއުމިނުން ދެނެވޮޑިގެންވެ، އެކަން ހާމަކުރެއްވުމަށްޓަކައެވެ.","",""],["₃ سورة آل عمران","167","وَلِيَعۡلَمَ ٱلَّذِينَ نَافَقُواْۚ وَقِيلَ لَهُمۡ تَعَالَوۡاْ قَٰتِلُواْ فِي سَبِيلِ ٱللَّهِ أَوِ ٱدۡفَعُواْۖ قَالُواْ لَوۡ نَعۡلَمُ قِتَالٗا لَّٱتَّبَعۡنَٰكُمۡۗ هُمۡ لِلۡكُفۡرِ يَوۡمَئِذٍ أَقۡرَبُ مِنۡهُمۡ لِلۡإِيمَٰنِۚ يَقُولُونَ بِأَفۡوَٰهِهِم مَّا لَيۡسَ فِي قُلُوبِهِمۡۚ وَٱللَّهُ أَعۡلَمُ بِمَا يَكۡتُمُونَ ١٦٧","وليعلم الذين نافقوا وقيل لهم تعالوا قاتلوا في سبيل الله أو ادفعوا قالوا لو نعلم قتالا لاتبعناكم هم للكفر يومئذ أقرب منهم للإيمان يقولون بأفواههم ما ليس في قلوبهم والله أعلم بما يكتمون","އަދި، މުނާފިގުވި މީހުން އެކަލާނގެ ދެނެވޮޑިގެންވެ، އެކަން ހާމަކުރެއްވުމަށްޓަކައެވެ. (އެދުވަހު) އެއުރެންނަށް އެންގެވިއެވެ. ﷲގެ މަގުގައި ހަނގުރާމަކުރަން ނުވަތަ (ޖާނާއި މާލު ދުޝްމަނުންގެ ކިބައިން) ދިފާޢުކުރަން ތިޔަބައިމީހުން އަންނާށެވެ! އެއުރެން ބުނެފޫއެވެ. ތިމަންމެންނަށް ހަނގުރާމައެއްވާކަން އެނގޭނަމަ، ތިޔަބައިމީހުންގެ ފަހަތުން ތިމަންމެން ދިޔައީމުހެވެ. އެދުވަހު އެއުރެން އީމާންކަމަށްވުރެ ކާފިރުކަމާ ގާތްކަން ބޮޑެވެ. އެއުރެންގެ ހިތްތަކުގައި ނުވާ ކަންތައް އެއުރެންގެ އަނގައިން ބުނެތެވެ. އެއުރެން ވަންހަނާކުރާ ކަންތައް އެންމެމޮޅަށް ދެނެވޮޑިގެންވަނީ ﷲއެވެ.","",""],["₃ سورة آل عمران","168","ٱلَّذِينَ قَالُواْ لِإِخۡوَٰنِهِمۡ وَقَعَدُواْ لَوۡ أَطَاعُونَا مَا قُتِلُواْۗ قُلۡ فَٱدۡرَءُواْ عَنۡ أَنفُسِكُمُ ٱلۡمَوۡتَ إِن كُنتُمۡ صَٰدِقِينَ ١٦٨","الذين قالوا لإخوانهم وقعدوا لو أطاعونا ما قتلوا قل فادرءوا عن أنفسكم الموت إن كنتم صادقين","އެއުރެންނީ ހަނގުރާމަޔަށް ނުނިކުމެތިބެ، އެއުރެންގެ އަޚުންނަށް ބުނި މީހުންނެވެ. ތިމަންމެންނަށް އެއުރެން ކިޔަމަންވީނަމަ، (އެބަހީ: ހަނގުރާމަޔަށް ނުނިކުމެ ތިބިނަމަ) އެއުރެން ގަތުލެއް ނުވީހެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ތެދުބުނާ ބަޔަކު ކަމުގައިވާނަމަ، މަރު، ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސު ތަކުން ދުރުކޮށްބަލާށެވެ!","",""],["₃ سورة آل عمران","169","وَلَا تَحۡسَبَنَّ ٱلَّذِينَ قُتِلُواْ فِي سَبِيلِ ٱللَّهِ أَمۡوَٰتَۢاۚ بَلۡ أَحۡيَآءٌ عِندَ رَبِّهِمۡ يُرۡزَقُونَ ١٦٩","ولا تحسبن الذين قتلوا في سبيل الله أمواتا بل أحياء عند ربهم يرزقون","ﷲގެ މަގުގައި ހަނގުރާމަކޮށް ޝަހީދު ވީ މީހުންނަކީ، މަރުވެފައިވާ ބަޔެކޭ ހީނުކުރާ ހުށިކަމެވެ! އަދި، ކިއެއްތަ! އެއުރެންނީ އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ރިޒްގު ލިބޭ ޙާލު، ދިރިތިބި ބަޔެކެވެ.","",""],["₃ سورة آل عمران","170","فَرِحِينَ بِمَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضۡلِهِۦ وَيَسۡتَبۡشِرُونَ بِٱلَّذِينَ لَمۡ يَلۡحَقُواْ بِهِم مِّنۡ خَلۡفِهِمۡ أَلَّا خَوۡفٌ عَلَيۡهِمۡ وَلَا هُمۡ يَحۡزَنُونَ ١٧٠","فرحين بما آتاهم الله من فضله ويستبشرون بالذين لم يلحقوا بهم من خلفهم ألا خوف عليهم ولا هم يحزنون","(އެއުރެން ތިބޭހުށީ) ﷲ، އެކަލާނގެ ފަޟްލު ވަންތަކަމުން އެއުރެންނަށް ދެއްވި ކަންތަކާމެދު، އުފާކުރާ ޙާލު ގައެވެ. އަދި، އެއުރެންގެ ފަހަތުން އައިސް އަދި، ބައްދަލުނުކޮށްތިބި މީހުންނާމެދު އެއުރެންގެ މައްޗަށް ބިރެއް ނެތްކަމަށާއި، އަދި، އެއުރެންނީ ހިތާމަކުރާނޭ ބަޔަކު ކަމުގައި ނުވާކަމާމެދު، އެއުރެން އުފާކުރާ ޙާލު ގައެވެ.","",""],["₃ سورة آل عمران","171","۞يَسۡتَبۡشِرُونَ بِنِعۡمَةٖ مِّنَ ٱللَّهِ وَفَضۡلٖ وَأَنَّ ٱللَّهَ لَا يُضِيعُ أَجۡرَ ٱلۡمُؤۡمِنِينَ ١٧١","يستبشرون بنعمة من الله وفضل وأن الله لا يضيع أجر المؤمنين","އެއުރެން (ވަނީ) ﷲގެ ހަޒުރަތުން ދެއްވާ ނިއުމަތާއި، ފަޟްލު ވަންތަކަމަށާއި، އަދި، ހަމަކަށަވަރުން ﷲ، މުއުމިނުންގެ ދަރުމަ ގެއްލެނި ނުކުރައްވާނޭކަމަށް އުފާކުރާ ގޮތުގައެވެ.","",""],["₃ سورة آل عمران","172","ٱلَّذِينَ ٱسۡتَجَابُواْ لِلَّهِ وَٱلرَّسُولِ مِنۢ بَعۡدِ مَآ أَصَابَهُمُ ٱلۡقَرۡحُۚ لِلَّذِينَ أَحۡسَنُواْ مِنۡهُمۡ وَٱتَّقَوۡاْ أَجۡرٌ عَظِيمٌ ١٧٢","الذين استجابوا لله والرسول من بعد ما أصابهم القرح للذين أحسنوا منهم واتقوا أجر عظيم","އެއީ، އެއުރެންނަށް ވޭނާއި، ހާނީއްކަ ލިބުމަށްފަހުވެސް، ﷲއާއި، ރަސޫލާއަށް އިޖާބަދިން މީހުންނެވެ. އެއުރެންގެ ތެރެއިން އިހްސާން ތެރިވެ ތަގުވާވެރިވި މީހުންނަށް ބޮޑުވެގެންވާ ދަރުމަ ހުށްޓެވެ.","",""],["₃ سورة آل عمران","173","ٱلَّذِينَ قَالَ لَهُمُ ٱلنَّاسُ إِنَّ ٱلنَّاسَ قَدۡ جَمَعُواْ لَكُمۡ فَٱخۡشَوۡهُمۡ فَزَادَهُمۡ إِيمَٰنٗا وَقَالُواْ حَسۡبُنَا ٱللَّهُ وَنِعۡمَ ٱلۡوَكِيلُ ١٧٣","الذين قال لهم الناس إن الناس قد جمعوا لكم فاخشوهم فزادهم إيمانا وقالوا حسبنا الله ونعم الوكيل","އެއީ، އެއުރެންނަށް މީސްތަކުން ބުނި މީހުންނެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނާ ދެކޮޅަށް މީސްތަކުން (ލަޝްކަރު) އެއްކޮށްފިއެވެ. ފަހެ، ތިޔަބައިމީހުން، އެއުރެންދެކެ ބިރުގަންނާށެވެ! ފަހެ، އެ ބަސް އެއުރެންނަށް އީމާން ކަން އިތުރުކުރިއެވެ. އަދި، އެއުރެން ބުނޫއެވެ. ތިމަންމެންނަށް، ﷲ ފުދެއެވެ. އަދި، ވަކީލުކުރެވޭ ފަރާތުގެ މޮޅުކަމާއެވެ!","",""],["₃ سورة آل عمران","174","فَٱنقَلَبُواْ بِنِعۡمَةٖ مِّنَ ٱللَّهِ وَفَضۡلٖ لَّمۡ يَمۡسَسۡهُمۡ سُوٓءٞ وَٱتَّبَعُواْ رِضۡوَٰنَ ٱللَّهِۗ وَٱللَّهُ ذُو فَضۡلٍ عَظِيمٍ ١٧٤","فانقلبوا بنعمة من الله وفضل لم يمسسهم سوء واتبعوا رضوان الله والله ذو فضل عظيم","ފަހެ، ﷲގެ ހަޒުރަތުން ދެއްވި ނިއުމަތާއި، ފަޟްލު ވަންތަވެރިކަމާއިގެން ގެއްލުމެއް ނުލިބި، އެއުރެން އެނބުރި އައޫއެވެ. އަދި، އެއުރެން ﷲގެ ރުއްސެވުންހުރި މަގަށް ތަބާ ވޫއެވެ. ﷲއީ، ބޮޑުވެގެންވާ ފަޟްލު ވަންތަކަމުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","175","إِنَّمَا ذَٰلِكُمُ ٱلشَّيۡطَٰنُ يُخَوِّفُ أَوۡلِيَآءَهُۥ فَلَا تَخَافُوهُمۡ وَخَافُونِ إِن كُنتُم مُّؤۡمِنِينَ ١٧٥","إنما ذلكم الشيطان يخوف أولياءه فلا تخافوهم وخافون إن كنتم مؤمنين","ހަމަކަށަވަރުން، އެއީ، ހަމަ ޝައިތާނާއެވެ. އެކަލޭގެ، އެކަލޭގެ އެކުވެރިން ދެކެ (ތިޔަބައިމީހުން) ބިރުގަންނަވަނީއެވެ. ފަހެ، ތިޔަބައިމީހުން އެއުރެންދެކެ ބިރުނުގަންނާށެވެ! އަދި، ތިޔަބައިމީހުން، މުއުމިނުން ކަމުގައިވާނަމަ، ތިމަންރަސްކަލާނގެއަށް ތިޔަބައިމީހުން ބިރުވެތިވާށެވެ!","",""],["₃ سورة آل عمران","176","وَلَا يَحۡزُنكَ ٱلَّذِينَ يُسَٰرِعُونَ فِي ٱلۡكُفۡرِۚ إِنَّهُمۡ لَن يَضُرُّواْ ٱللَّهَ شَيۡـٔٗاۗ يُرِيدُ ٱللَّهُ أَلَّا يَجۡعَلَ لَهُمۡ حَظّٗا فِي ٱلۡأٓخِرَةِۖ وَلَهُمۡ عَذَابٌ عَظِيمٌ ١٧٦","ولا يحزنك الذين يسارعون في الكفر إنهم لن يضروا الله شيئا يريد الله ألا يجعل لهم حظا في الآخرة ولهم عذاب عظيم","ކާފިރު ވުމުގައި، އަވަސްވެގަންނަ މީހުން ކަލޭގެފާނު ހިތާމަވެރި ކުރުވިޔަ ނުދެއްވާށެވެ! ހަމަކަށަވަރުން، އެއްވެސްކަމަކުން އެއުރެންނަކަށް ﷲއަށް ގެއްލުމެއް ނުދެވޭނެތެވެ. ﷲ އިރާދަކުރައްވަނީ، އެއުރެންނަށް އާޚިރަތުގައި އެއްވެސް ނަސީބެއް ނުލެއްވުމަށެވެ. އަދި، އެއުރެންނަށް ބޮޑުވެގެންވާ އަޒާބު ހުށްޓެވެ.","",""],["₃ سورة آل عمران","177","إِنَّ ٱلَّذِينَ ٱشۡتَرَوُاْ ٱلۡكُفۡرَ بِٱلۡإِيمَٰنِ لَن يَضُرُّواْ ٱللَّهَ شَيۡـٔٗاۖ وَلَهُمۡ عَذَابٌ أَلِيمٞ ١٧٧","إن الذين اشتروا الكفر بالإيمان لن يضروا الله شيئا ولهم عذاب أليم","ހަމަކަށަވަރުން، އީމާންކަމުގެ ބަދަލުގައި ކާފިރު ކަން ގަތްމީހުންނަކަށް އެއްވެސްކަމަކުން ﷲއަށް ގެއްލުމެއް ނުދެވޭނެތެވެ. އަދި، އެއުރެންނަށް ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["₃ سورة آل عمران","178","وَلَا يَحۡسَبَنَّ ٱلَّذِينَ كَفَرُوٓاْ أَنَّمَا نُمۡلِي لَهُمۡ خَيۡرٞ لِّأَنفُسِهِمۡۚ إِنَّمَا نُمۡلِي لَهُمۡ لِيَزۡدَادُوٓاْ إِثۡمٗاۖ وَلَهُمۡ عَذَابٞ مُّهِينٞ ١٧٨","ولا يحسبن الذين كفروا أنما نملي لهم خير لأنفسهم إنما نملي لهم ليزدادوا إثما ولهم عذاب مهين","ތިމަންރަސްކަލާނގެ އެއުރެންނަށް (ޖަޒާ ދެއްވުމުގައި) ލަސްކުރެއްވުން އެއީ، އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް ހެޔޮގޮތެއްކަމަށް ކާފިރުވި މީހުން ހީނުކުރާހުށިކަމެވެ! ތިމަންރަސްކަލާނގެ އެއުރެންނަށް އެކަން ލަސްކުރައްވާކަން ކަށަވަރީ، އެއުރެންގެ ފާފަ އިތުރުވުމަށެވެ. އަދި، އެއުރެންނަށް އިހާނަތްތެރިކަން ދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["₃ سورة آل عمران","179","مَّا كَانَ ٱللَّهُ لِيَذَرَ ٱلۡمُؤۡمِنِينَ عَلَىٰ مَآ أَنتُمۡ عَلَيۡهِ حَتَّىٰ يَمِيزَ ٱلۡخَبِيثَ مِنَ ٱلطَّيِّبِۗ وَمَا كَانَ ٱللَّهُ لِيُطۡلِعَكُمۡ عَلَى ٱلۡغَيۡبِ وَلَٰكِنَّ ٱللَّهَ يَجۡتَبِي مِن رُّسُلِهِۦ مَن يَشَآءُۖ فَـَٔامِنُواْ بِٱللَّهِ وَرُسُلِهِۦۚ وَإِن تُؤۡمِنُواْ وَتَتَّقُواْ فَلَكُمۡ أَجۡرٌ عَظِيمٞ ١٧٩","ما كان الله ليذر المؤمنين على ما أنتم عليه حتى يميز الخبيث من الطيب وما كان الله ليطلعكم على الغيب ولكن الله يجتبي من رسله من يشاء فآمنوا بالله ورسله وإن تؤمنوا وتتقوا فلكم أجر عظيم","ރަނގަޅު މީހުންގެ ތެރެއިން ނުބައިމީހުން ވަކިކުރައްވައިފުމަށް ދާނދެން، ﷲ ތިޔަބައިމީހުން ތިބިގޮތުގެ މައްޗަށް (އެބަހީ: މުއުމިންނާއި މުނާފިގުން އެކުވެ އުޅުމުގެ މައްޗަށް) މުއުމިނުން ދުލެއް ނުކުރައްވާނެތެވެ. އަދި، ޣައިބުގެ ކަންތައް ﷲ، ތިޔަބައިމީހުންނަށް ފާޅެއް ނުކުރައްވާނެތެވެ. އެހެނެއްކަމަކު، ﷲ، އެކަލާނގެ ރަސޫލުންގެ ތެރެއިން އެކަލާނގެ އިރާދަކުރައްވާ ބަޔަކު ޚިޔާރުކުރައްވަތެވެ. ފަހެ، ތިޔަބައިމީހުން ﷲއަށާއި، އެކަލާނގެ ރަސޫލުންނަށް އީމާން ވާށެވެ! އަދި، ތިޔަބައިމީހުން އީމާންވެ، ތަގުވާވެރިވާނަމަ، ފަހެ، ތިޔަބައިމީހުންނަށް ބޮޑުވެގެންވާ ދަރުމަ ހުށްޓެވެ.","",""],["₃ سورة آل عمران","180","وَلَا يَحۡسَبَنَّ ٱلَّذِينَ يَبۡخَلُونَ بِمَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضۡلِهِۦ هُوَ خَيۡرٗا لَّهُمۖ بَلۡ هُوَ شَرّٞ لَّهُمۡۖ سَيُطَوَّقُونَ مَا بَخِلُواْ بِهِۦ يَوۡمَ ٱلۡقِيَٰمَةِۗ وَلِلَّهِ مِيرَٰثُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِۗ وَٱللَّهُ بِمَا تَعۡمَلُونَ خَبِيرٞ ١٨٠","ولا يحسبن الذين يبخلون بما آتاهم الله من فضله هو خيرا لهم بل هو شر لهم سيطوقون ما بخلوا به يوم القيامة ولله ميراث السماوات والأرض والله بما تعملون خبير","ﷲ، އެކަލާނގެ ފަޟްލު ވަންތަކަމުގެ ތެރެއިން އެއުރެންނަށް ދެއްވި ތަކެއްޗާމެދު، ދަހިވެތިވާ މީހުން، އެކަންއެއީ، އެއުރެންނަށްހުރި ހެޔޮކަމެއް ކަމުގައި ހީނުކުރާހުށިކަމެވެ! އަދި ކިއެއްތަ! އެއީ، އެއުރެންނަށްހުރި ނުބައިކަމެކެވެ. އެއުރެން ދަހިވެތިވި ތަކެތީން ގިޔާމަތް ދުވަހުން އެއުރެންގެ ކަރުގައި ކަސްތަޅު އަޅުއްވާ ހުށްޓެވެ. އުޑުތަކާއި ބިމުގެ މަލަކަވެރިކަންވަނީ ﷲއަށެވެ. އަދި، ﷲއީ، ތިޔަބައިމީހުންކުރާ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","181","لَّقَدۡ سَمِعَ ٱللَّهُ قَوۡلَ ٱلَّذِينَ قَالُوٓاْ إِنَّ ٱللَّهَ فَقِيرٞ وَنَحۡنُ أَغۡنِيَآءُۘ سَنَكۡتُبُ مَا قَالُواْ وَقَتۡلَهُمُ ٱلۡأَنۢبِيَآءَ بِغَيۡرِ حَقّٖ وَنَقُولُ ذُوقُواْ عَذَابَ ٱلۡحَرِيقِ ١٨١","لقد سمع الله قول الذين قالوا إن الله فقير ونحن أغنياء سنكتب ما قالوا وقتلهم الأنبياء بغير حق ونقول ذوقوا عذاب الحريق","ހަމަކަށަވަރުން، ﷲއީ ފަގީރު އެކޭ، ތިމަންމެންނީ މުއްސަނދިންނޭ ބުނިމީހުންގެ ބުނުން، ﷲ އައްސަވާވޮޑިގެންފިކަން ކަށަވަރެވެ. އެއުރެން ބުނި ބުނުމާއި، އެއުރެން ހައްގަކާނުލައި ނަބިއްޔުން ގަތުލުކުޅަކަން ނިކަންހުރެ ތިމަންރަސްކަލާނގެ ލިޔުއްވާހުށީމެވެ. އަދި، (ގިޔާމަތް ދުވަހުން އެއުރެންނަށް) ތިމަންރަސްކަލާނގެ ވަހީކުރައްވާހުށީމެވެ. ތިޔަބައިމީހުން، އަނދައަނދާހުރި ނަރަކައިގެ އަޒާބުގެ ރަހަ ލިބިގަންނާށެވެ!","",""],["₃ سورة آل عمران","182","ذَٰلِكَ بِمَا قَدَّمَتۡ أَيۡدِيكُمۡ وَأَنَّ ٱللَّهَ لَيۡسَ بِظَلَّامٖ لِّلۡعَبِيدِ ١٨٢","ذلك بما قدمت أيديكم وأن الله ليس بظلام للعبيد","އެއީ، ތިޔަބައިމީހުންގެ އަތްތަކުން އިސްކުޅަ ކަންތަކުގެ ސަބަބުންނެވެ. އަދި، ހަމަކަށަވަރުން ﷲއީ، އަޅުތަކުންނަށް އަނިޔާވެރިވެވޮޑިގެންވާ ކަލަކުކަމުގައި ނުވެއެވެ.","",""],["₃ سورة آل عمران","183","ٱلَّذِينَ قَالُوٓاْ إِنَّ ٱللَّهَ عَهِدَ إِلَيۡنَآ أَلَّا نُؤۡمِنَ لِرَسُولٍ حَتَّىٰ يَأۡتِيَنَا بِقُرۡبَانٖ تَأۡكُلُهُ ٱلنَّارُۗ قُلۡ قَدۡ جَآءَكُمۡ رُسُلٞ مِّن قَبۡلِي بِٱلۡبَيِّنَٰتِ وَبِٱلَّذِي قُلۡتُمۡ فَلِمَ قَتَلۡتُمُوهُمۡ إِن كُنتُمۡ صَٰدِقِينَ ١٨٣","الذين قالوا إن الله عهد إلينا ألا نؤمن لرسول حتى يأتينا بقربان تأكله النار قل قد جاءكم رسل من قبلي بالبينات وبالذي قلتم فلم قتلتموهم إن كنتم صادقين","އެއުރެންނީ، އަލިފާން އެ ގުރުބާނެއް ކައިލާ، ގުރުބާނަކާއިގެން ތިމަންމެންގެ ގާތަށް ވަޑައިގެންފުމަށްދާނދެން، އެއްވެސް ރަސޫލަކަށް އީމާން ނުވުމަށް ހަމަކަށަވަރުން ﷲ ތިމަންމެންނަށް އަންގަވާފައިވެޔޭ ބުނި މީހުންނެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ބަޔާންވެގެންހުރި ހެކިތަކާއި، ތިޔަބައިމީހުން ތިޔަބުނި ކަންތަކާއިގެން، ތިމަންކަލޭގެފާނުގެ ކުރިން ހަމަކަށަވަރުން ތިޔަބައިމީހުންގެ ގާތަށް ރަސޫލުން ވަޑައިގަތެވެ. ތިޔަބައިމީހުންނީ ތެދުބުނާ މީހުންކަމުގައިވާނަމަ ތިޔަބައިމީހުން އެ ރަސޫލުން ގަތުލުކުޅައީ ފަހެ، ކީއްވެގެން ހެއްޔެވެ؟","",""],["₃ سورة آل عمران","184","فَإِن كَذَّبُوكَ فَقَدۡ كُذِّبَ رُسُلٞ مِّن قَبۡلِكَ جَآءُو بِٱلۡبَيِّنَٰتِ وَٱلزُّبُرِ وَٱلۡكِتَٰبِ ٱلۡمُنِيرِ ١٨٤","فإن كذبوك فقد كذب رسل من قبلك جاءوا بالبينات والزبر والكتاب المنير","ފަހެ، އެއުރެން ކަލޭގެފާނު ދޮގުކުޅަނަމަ، (ދެނެވަޑައިގަންނަވާށެވެ!) ފަހެ، ހަމަކަށަވަރުން ކަލޭގެފާނުގެ ކުރިންވެސް ރަސޫލުން ދޮގު ކުޅައޫއެވެ. އެބޭކަލުން ވަޑައިގަތީ، ފާޅުވެގެންހުރި ހެކިތަކާއި، ލިޔުއްވާފައިވާ ފަތްފުށްތަކާއި، އަލިކުރަނިވި ފޮތާއިގެންނެވެ.","",""],["₃ سورة آل عمران","185","كُلُّ نَفۡسٖ ذَآئِقَةُ ٱلۡمَوۡتِۗ وَإِنَّمَا تُوَفَّوۡنَ أُجُورَكُمۡ يَوۡمَ ٱلۡقِيَٰمَةِۖ فَمَن زُحۡزِحَ عَنِ ٱلنَّارِ وَأُدۡخِلَ ٱلۡجَنَّةَ فَقَدۡ فَازَۗ وَمَا ٱلۡحَيَوٰةُ ٱلدُّنۡيَآ إِلَّا مَتَٰعُ ٱلۡغُرُورِ ١٨٥","كل نفس ذائقة الموت وإنما توفون أجوركم يوم القيامة فمن زحزح عن النار وأدخل الجنة فقد فاز وما الحياة الدنيا إلا متاع الغرور","ކޮންމެ ނަފްސަކީވެސް، މަރުގެ ރަހަ ލިބިގަންނާނޭ އެއްޗެކެވެ. އަދި، (ތިޔަބައިމީހުން ކުޅަ ޢަމަލުތަކަށް) ތިޔަބައިމީހުންނަށް ފުރިހަމަޔަށް ޖަޒާ ދެއްވާނެކަން ކަށަވަރީ، ގިޔާމަތް ދުވަހުންނެވެ. ފަހެ، ނަރަކައިން އެއްކިބާކުރައްވައި، ސުވަރުގެޔަށް ވެއްދެވި މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކު ނަސީބު ލިބިގެންފިކަން ކަށަވަރެވެ. ކެހިވެރިކަމުގެ ވަގުތީ އުފަލެއް ދޭ އެއްޗެއްކަމުގައި މެނުވީ، ދުނިޔޭގެ ދިރިއުޅުން ނުވެއެވެ.","",""],["₃ سورة آل عمران","186","۞لَتُبۡلَوُنَّ فِيٓ أَمۡوَٰلِكُمۡ وَأَنفُسِكُمۡ وَلَتَسۡمَعُنَّ مِنَ ٱلَّذِينَ أُوتُواْ ٱلۡكِتَٰبَ مِن قَبۡلِكُمۡ وَمِنَ ٱلَّذِينَ أَشۡرَكُوٓاْ أَذٗى كَثِيرٗاۚ وَإِن تَصۡبِرُواْ وَتَتَّقُواْ فَإِنَّ ذَٰلِكَ مِنۡ عَزۡمِ ٱلۡأُمُورِ ١٨٦","لتبلون في أموالكم وأنفسكم ولتسمعن من الذين أوتوا الكتاب من قبلكم ومن الذين أشركوا أذى كثيرا وإن تصبروا وتتقوا فإن ذلك من عزم الأمور","ތިޔަބައިމީހުންގެ މުދާތަކާއި، ނަފްސު ތަކާ މެދުގައި، ތިޔަބައިމީހުން އިމްތިހާނުކުރައްވާނެކަން ކަށަވަރެވެ. އަދި، ތިޔަބައިމީހުންގެ ކުރިން ފޮތް ލިބުނު މީހުންގެ ކިބައިންނާއި، ޝަރީކުކުޅަ މީހުންގެ ކިބައިން، ގިނަވެގެންވާ އުނދަގޫތައް (އެބަހީ: ނުރުހެވޭ ބަސްތައް) ތިޔަބައިމީހުންނަށް އިވޭނެކަން ކަށަވަރެވެ. ތިޔަބައިމީހުން ކެތްތެރިވެ، ތަގުވާވެރިވާނަމަ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އެކަންކަންވަނީ، ޢަޒުމު ކަނޑައަޅަންޖެހޭ ކަންތައްތަކުގެ ތެރެއިންނެވެ.","",""],["₃ سورة آل عمران","187","وَإِذۡ أَخَذَ ٱللَّهُ مِيثَٰقَ ٱلَّذِينَ أُوتُواْ ٱلۡكِتَٰبَ لَتُبَيِّنُنَّهُۥ لِلنَّاسِ وَلَا تَكۡتُمُونَهُۥ فَنَبَذُوهُ وَرَآءَ ظُهُورِهِمۡ وَٱشۡتَرَوۡاْ بِهِۦ ثَمَنٗا قَلِيلٗاۖ فَبِئۡسَ مَا يَشۡتَرُونَ ١٨٧","وإذ أخذ الله ميثاق الذين أوتوا الكتاب لتبيننه للناس ولا تكتمونه فنبذوه وراء ظهورهم واشتروا به ثمنا قليلا فبئس ما يشترون","ފޮތް ލިބުނު މީހުންގެ ކިބައިން ﷲ، އަހުދު ކަށަވަރު ހިއްޕެވިހިނދު ހަނދުމަ ކުރާށެވެ! އެ އަހުދަކީ ތިޔަބައިމީހުން މީސްތަކުންނަށް އެ ފޮތް ބަޔާން ކޮށް ދިނުމަށާއި، އެ ފޮތް ވަންހަނާ ނުކުރުމަށް ހިއްޕެވި އަހުދެވެ. ދެން، އެއުރެންގެ ފުރަގަހަށް އެ އަހުދެއްލައިލިއެވެ. އަދި، އެއުރެން އެ ފޮތަށް ކުޑައަގެއް ގަތެވެ. ފަހެ، އެއުރެން އެ ގަންނަ ތަކެތީގެ ނުބައިކަމާއެވެ!","",""],["₃ سورة آل عمران","188","لَا تَحۡسَبَنَّ ٱلَّذِينَ يَفۡرَحُونَ بِمَآ أَتَواْ وَّيُحِبُّونَ أَن يُحۡمَدُواْ بِمَا لَمۡ يَفۡعَلُواْ فَلَا تَحۡسَبَنَّهُم بِمَفَازَةٖ مِّنَ ٱلۡعَذَابِۖ وَلَهُمۡ عَذَابٌ أَلِيمٞ ١٨٨","لا تحسبن الذين يفرحون بما أتوا ويحبون أن يحمدوا بما لم يفعلوا فلا تحسبنهم بمفازة من العذاب ولهم عذاب أليم","އެއުރެންކުޅަ ކަންތަކަށް އުފާކުރާ، އަދި، އެއުރެން ނުކުރާ ކަންތަކާމެދު ތާރީފު ލިބުމަށް އެދޭމީހުންނީ، އަޒާބުން ސަލާމަތްވާނެ ތަނެއްގައި ތިބިބަޔަކު ކަމުގައި ހީނުކުރާހުށިކަމެވެ! އެއުރެންނަށް ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["₃ سورة آل عمران","189","وَلِلَّهِ مُلۡكُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِۗ وَٱللَّهُ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٌ ١٨٩","ولله ملك السماوات والأرض والله على كل شيء قدير","އަދި، އުޑުތަކާއި ބިމުގެ ވެރިކަންވަނީ ﷲއަށެވެ. އަދި، ﷲއީ، ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","190","إِنَّ فِي خَلۡقِ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ وَٱخۡتِلَٰفِ ٱلَّيۡلِ وَٱلنَّهَارِ لَأٓيَٰتٖ لِّأُوْلِي ٱلۡأَلۡبَٰبِ ١٩٠","إن في خلق السماوات والأرض واختلاف الليل والنهار لآيات لأولي الألباب","ހަމަކަށަވަރުން، އުޑުތަކާއި ބިން ހެއްދެވުމުގައްޔާއި ރޭދުވާ ތަފާތުވުމުގައި، ބުއްދީގެ އަހުލުވެރިންނަށް ކަށަވަރުވެގެންހުރި ހެކިތަކެއްވެއެވެ.","",""],["₃ سورة آل عمران","191","ٱلَّذِينَ يَذۡكُرُونَ ٱللَّهَ قِيَٰمٗا وَقُعُودٗا وَعَلَىٰ جُنُوبِهِمۡ وَيَتَفَكَّرُونَ فِي خَلۡقِ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ رَبَّنَا مَا خَلَقۡتَ هَٰذَا بَٰطِلٗا سُبۡحَٰنَكَ فَقِنَا عَذَابَ ٱلنَّارِ ١٩١","الذين يذكرون الله قياما وقعودا وعلى جنوبهم ويتفكرون في خلق السماوات والأرض ربنا ما خلقت هذا باطلا سبحانك فقنا عذاب النار","އެއުރެންނީ، ކޮޅަށް ތިބެގެންނާއި، އިށީނދެތިބެގެންނާއި، އޮށޯވެތިބެގެން، ﷲ ހަނދުމަކޮށް، އުޑުތަކާއި ބިން ހެއްދެވުމާމެދު، ފިކުރުކޮށް އުޅޭމީހުންނެވެ. (އެއުރެން ދަންނަވާނެތެވެ.) އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އިބަރަސްކަލާނގެ މިތަކެތި ހައްދަވާފައިވަނީ، ބާތިލު ގޮތެއްގައެއް ނޫނެވެ. އިބަރަސްކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! ފަހެ، ނަރަކައިގެ އަޒާބުން އަޅަމެން ދިންނަވާނދޭވެ!","",""],["₃ سورة آل عمران","192","رَبَّنَآ إِنَّكَ مَن تُدۡخِلِ ٱلنَّارَ فَقَدۡ أَخۡزَيۡتَهُۥۖ وَمَا لِلظَّـٰلِمِينَ مِنۡ أَنصَارٖ ١٩٢","ربنا إنك من تدخل النار فقد أخزيته وما للظالمين من أنصار","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެ ނަރަކަޔަށް ވައްދަވައިފިމީހާ، ފަހެ، އިބަރަސްކަލާނގެ އެމީހަކު ނިކަމެތި ކުރައްވައިފިކަން ކަށަވަރެވެ. އަނިޔާވެރިންނަށް ނަސްރު ދޭނެ އެއްވެސް ބަޔަކު ނުވެއެވެ.","",""],["₃ سورة آل عمران","193","رَّبَّنَآ إِنَّنَا سَمِعۡنَا مُنَادِيٗا يُنَادِي لِلۡإِيمَٰنِ أَنۡ ءَامِنُواْ بِرَبِّكُمۡ فَـَٔامَنَّاۚ رَبَّنَا فَٱغۡفِرۡ لَنَا ذُنُوبَنَا وَكَفِّرۡ عَنَّا سَيِّـَٔاتِنَا وَتَوَفَّنَا مَعَ ٱلۡأَبۡرَارِ ١٩٣","ربنا إننا سمعنا مناديا ينادي للإيمان أن آمنوا بربكم فآمنا ربنا فاغفر لنا ذنوبنا وكفر عنا سيئاتنا وتوفنا مع الأبرار","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އީމާން ވުމަށް ގޮވާލައްވާ ރަސޫލަކު ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެޔަށް އީމާން ވާށޭ ގޮވާލައްވާ އަޑު، ހަމަކަށަވަރުން، އަޅަމެން އެހީމުއެވެ. ދެން، އަޅަމެން އީމާން ވީމުއެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ފަހެ، އަޅަމެންނަށް އަޅަމެންގެ ފާފަތައް ފުއްސަވާނދޭވެ! އަދި، އަޅަމެންގެ ކިބައިން އަޅަމެންގެ ކުށްތައް އަފޫކުރައްވާނދޭވެ! އަދި، ހެޔޮލަފާ މީހުންނާއެކު އަޅަމެން މަރުގަންނަވާނދޭވެ!","",""],["₃ سورة آل عمران","194","رَبَّنَا وَءَاتِنَا مَا وَعَدتَّنَا عَلَىٰ رُسُلِكَ وَلَا تُخۡزِنَا يَوۡمَ ٱلۡقِيَٰمَةِۖ إِنَّكَ لَا تُخۡلِفُ ٱلۡمِيعَادَ ١٩٤","ربنا وآتنا ما وعدتنا على رسلك ولا تخزنا يوم القيامة إنك لا تخلف الميعاد","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އިބަރަސްކަލާނގެ ރަސޫލުންގެ ދޫފުޅުމަތީން އަޅަމެންނަށް ވައުދުކުރައްވާފައިވާ ކަންތައް، އަޅަމެންނަށް ދެއްވާނދޭވެ! އަދި، ގިޔާމަތް ދުވަހުން އަޅަމެން ނިކަމެތި ނުކުރައްވާނދޭވެ! ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެ ވައުދާ ޚިލާފުވެ ވޮޑިއެއް ނުގަންނަވަމުއެވެ.","",""],["₃ سورة آل عمران","195","فَٱسۡتَجَابَ لَهُمۡ رَبُّهُمۡ أَنِّي لَآ أُضِيعُ عَمَلَ عَٰمِلٖ مِّنكُم مِّن ذَكَرٍ أَوۡ أُنثَىٰۖ بَعۡضُكُم مِّنۢ بَعۡضٖۖ فَٱلَّذِينَ هَاجَرُواْ وَأُخۡرِجُواْ مِن دِيَٰرِهِمۡ وَأُوذُواْ فِي سَبِيلِي وَقَٰتَلُواْ وَقُتِلُواْ لَأُكَفِّرَنَّ عَنۡهُمۡ سَيِّـَٔاتِهِمۡ وَلَأُدۡخِلَنَّهُمۡ جَنَّـٰتٖ تَجۡرِي مِن تَحۡتِهَا ٱلۡأَنۡهَٰرُ ثَوَابٗا مِّنۡ عِندِ ٱللَّهِۚ وَٱللَّهُ عِندَهُۥ حُسۡنُ ٱلثَّوَابِ ١٩٥","فاستجاب لهم ربهم أني لا أضيع عمل عامل منكم من ذكر أو أنثى بعضكم من بعض فالذين هاجروا وأخرجوا من ديارهم وأوذوا في سبيلي وقاتلوا وقتلوا لأكفرن عنهم سيئاتهم ولأدخلنهم جنات تجري من تحتها الأنهار ثوابا من عند الله والله عنده حسن الثواب","ދެން، އެއުރެންގެ ވެރިރަސްކަލާނގެ، އެއުރެންގެ ދުއާ އިޖާބަ ކުރެއްވިއެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ތެރެއިން ފިރިހެނުންކުރެ ނުވަތަ އަންހެނުންކުރެ، ޢަމަލުކުރާ މީހެއްގެ ޢަމަލު، ތިމަންރަސްކަލާނގެ ގެއްލެނި ނުކުރައްވާހުށީމެވެ. ތިޔަބައިމީހުންކުރެ އެއްބަޔަކުވަނީ އަނެއްބަޔެއްގެ ކިބައިންނެވެ. ފަހެ، އެއުރެން ހިޖުރަ ކޮށް އެއުރެންގެ ގޮވަތިގެދޮރުން ނެރެވި، ތިމަންރަސްކަލާނގެ މަގުގައި އެއުރެންނަށް އުނދަގޫލިބި، ހަނގުރާމަކޮށް، އަދި ގަތުލު ވީ މީހުންގެ ކިބައިން އެއުރެންގެ ކުށްފާފަތައް ހަމަކަށަވަރުން ތިމަންރަސްކަލާނގެ ފުއްސަވާހުށީމެވެ. އަދި، އެތަންތާނގެ ދަށުން ކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކަށް ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެން ވައްދަވާހުށީމެވެ. ﷲގެ ހަޒުރަތުން ލިބޭ ސަވާބެއްގެ ގޮތުގައެވެ. ރިވެތިވެގެންވާ ސަވާބު ވަނީ ﷲގެ ހަޒުރަތު ގައެވެ.","",""],["₃ سورة آل عمران","196","لَا يَغُرَّنَّكَ تَقَلُّبُ ٱلَّذِينَ كَفَرُواْ فِي ٱلۡبِلَٰدِ ١٩٦","لا يغرنك تقلب الذين كفروا في البلاد","ކާފިރުވި މީހުން ރަށްތަކުގައި އެގޮތްމިގޮތަށް އުޅޭއުޅުން ކަލޭގެފާނު ހެއްލުންތެރި ކުރިއަ ނުދޭހުށިކަމެވެ!","",""],["₃ سورة آل عمران","197","مَتَٰعٞ قَلِيلٞ ثُمَّ مَأۡوَىٰهُمۡ جَهَنَّمُۖ وَبِئۡسَ ٱلۡمِهَادُ ١٩٧","متاع قليل ثم مأواهم جهنم وبئس المهاد","(އެއީ) ކުޑަކުޑަ ވަގުތީ އަރާމެކެވެ. ދެން، އެއުރެން ތިބެނިވި ތަނަކީ ނަރަކައެވެ. އަދި، އެ ތަންމަތީގެ ހުރި ނުބައިކަމާއެވެ!","",""],["₃ سورة آل عمران","198","لَٰكِنِ ٱلَّذِينَ ٱتَّقَوۡاْ رَبَّهُمۡ لَهُمۡ جَنَّـٰتٞ تَجۡرِي مِن تَحۡتِهَا ٱلۡأَنۡهَٰرُ خَٰلِدِينَ فِيهَا نُزُلٗا مِّنۡ عِندِ ٱللَّهِۗ وَمَا عِندَ ٱللَّهِ خَيۡرٞ لِّلۡأَبۡرَارِ ١٩٨","لكن الذين اتقوا ربهم لهم جنات تجري من تحتها الأنهار خالدين فيها نزلا من عند الله وما عند الله خير للأبرار","އެހެނެއްކަމަކު އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ތަގުވާވެރިވި މީހުންނަށް، އެތަންތާނގެ ދަށުން ކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތައް ހުށްޓެވެ. އެތަންތާނގައި، އެއުރެން ދެމިތިބޭ ޙާލު ގައެވެ. ﷲގެ ހަޒުރަތުން ލިބޭ ޝަރަފެއްގެ ގޮތުގައެވެ. ﷲގެ ހަޒުރަތު ގައިވާ ކަންތައް ހެޔޮލަފާ މީހުންނަށް، މާހެޔޮވެގެން ވެއެވެ.","",""],["₃ سورة آل عمران","199","وَإِنَّ مِنۡ أَهۡلِ ٱلۡكِتَٰبِ لَمَن يُؤۡمِنُ بِٱللَّهِ وَمَآ أُنزِلَ إِلَيۡكُمۡ وَمَآ أُنزِلَ إِلَيۡهِمۡ خَٰشِعِينَ لِلَّهِ لَا يَشۡتَرُونَ بِـَٔايَٰتِ ٱللَّهِ ثَمَنٗا قَلِيلًاۚ أُوْلَـٰٓئِكَ لَهُمۡ أَجۡرُهُمۡ عِندَ رَبِّهِمۡۗ إِنَّ ٱللَّهَ سَرِيعُ ٱلۡحِسَابِ ١٩٩","وإن من أهل الكتاب لمن يؤمن بالله وما أنزل إليكم وما أنزل إليهم خاشعين لله لا يشترون بآيات الله ثمنا قليلا أولئك لهم أجرهم عند ربهم إن الله سريع الحساب","ހަމަކަށަވަރުން، ﷲއަށް އީމާންވާ، އަދި، ތިޔަބައިމީހުންނަށް ބާވައިލެއްވި ފޮތަށާއި، އެއުރެންނަށް ބާވައިލެއްވި ފޮތަށް އީމާންވާ މީހުން ހަމަކަށަވަރުން، ފޮތުގެ އަހުލުވެރިންގެ ތެރެއިންވެއެވެ. އެއުރެން ﷲއަށް މަޑުމައިތިރިވެގެންވާ ޙާލު ގައެވެ. ﷲގެ އާޔަތްތަކަށް އެއުރެން ކުޑައަގެއް ނުގަނެތެވެ. އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި، އެއުރެންގެ ދަރުމަ އެއުރެންނަށް ހުށްޓެވެ. ހަމަކަށަވަރުން، ﷲއީ، ހިސާބު ބެއްލެވުން އަވަސްވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₃ سورة آل عمران","200","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ ٱصۡبِرُواْ وَصَابِرُواْ وَرَابِطُواْ وَٱتَّقُواْ ٱللَّهَ لَعَلَّكُمۡ تُفۡلِحُونَ ٢٠٠","يا أيها الذين آمنوا اصبروا وصابروا ورابطوا واتقوا الله لعلكم تفلحون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ކެތްކުރާށެވެ! އަދި، (ދުޝްމަނުންނާ ހަނގުރާމަ ކުރުމުގައި އެއުރެންނަށްވުރެ ބޮޑަށް) ތިޔަބައިމީހުން ކެތްތެރިވާށެވެ! އަދި، ދުޝްމަނުން އަތުވެދާނޭ މަގުތަކަށް ބަލަބަލާ ޖިހާދުކުރުމަށް ތައްޔާރީގައި ތިބޭށެވެ! އަދި، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! (އެއީ) ތިޔަބައިމީހުން ދިންނަވައި ނަސީބު ލިބުމަށްޓަކައެވެ.","",""],["₄ سورة النساء","1","بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ\n<br><br>\nيَـٰٓأَيُّهَا ٱلنَّاسُ ٱتَّقُواْ رَبَّكُمُ ٱلَّذِي خَلَقَكُم مِّن نَّفۡسٖ وَٰحِدَةٖ وَخَلَقَ مِنۡهَا زَوۡجَهَا وَبَثَّ مِنۡهُمَا رِجَالٗا كَثِيرٗا وَنِسَآءٗۚ وَٱتَّقُواْ ٱللَّهَ ٱلَّذِي تَسَآءَلُونَ بِهِۦ وَٱلۡأَرۡحَامَۚ إِنَّ ٱللَّهَ كَانَ عَلَيۡكُمۡ رَقِيبٗا ١","بسم الله الرحمن الرحيم يا أيها الناس اتقوا ربكم الذي خلقكم من نفس واحدة وخلق منها زوجها وبث منهما رجالا كثيرا ونساء واتقوا الله الذي تساءلون به والأرحام إن الله كان عليكم رقيبا","އޭ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއަށް ތިޔަބައިމީހުން ތަގުވާވެރިވާށެވެ! އެކަލާނގެއީ، އެންމެ ނަފްސަކުން ތިޔަބައިމީހުން ހެއްދެވި ރަސްކަލާނގެއެވެ. އަދި، އެ ނަފްސުގެ ކިބައިން އޭގެ އަނެއް ޖިންސު ހެއްދެވިއެވެ. އަދި، އެ ދެކަނބަލުންގެ ކިބައިން، ގިނަ ފިރިހެނުންނާއި، ގިނަ އަންހެނުން ފެތުރުއްވިއެވެ. އަދި، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އެކަލާނގެއީ، އެކަލާނގެ މެދުވެރިކޮށް ތިޔަބައިމީހުން އެކަކު އަނެކަކާ ސުވާލު ކޮށް، ކަންކަމަށް އެދިއުޅޭ ރަސްކަލާނގެއެވެ. އަދި، ތިމާގެކަމުގެ ގުޅުންތަކަށް ތިޔަބައިމީހުން ރައްކާތެރިވާށެވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ކަންތައް ބައްލަވާވޮޑިގެންވާ ކަލަކު ކަމުގައި، ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","2","وَءَاتُواْ ٱلۡيَتَٰمَىٰٓ أَمۡوَٰلَهُمۡۖ وَلَا تَتَبَدَّلُواْ ٱلۡخَبِيثَ بِٱلطَّيِّبِۖ وَلَا تَأۡكُلُوٓاْ أَمۡوَٰلَهُمۡ إِلَىٰٓ أَمۡوَٰلِكُمۡۚ إِنَّهُۥ كَانَ حُوبٗا كَبِيرٗا ٢","وآتوا اليتامى أموالهم ولا تتبدلوا الخبيث بالطيب ولا تأكلوا أموالهم إلى أموالكم إنه كان حوبا كبيرا","ޔަތީމުންނަށް (އެކުދިން ތަޞައްރަފު ފުދިއްޖެނަމަ) އެކުދިންގެ މުދާތައް ތިޔަބައިމީހުން ދޭށެވެ! އަދި، އޭގެތެރެއިން މޮޅުތަކެއްޗަށް ދެރަތަކެތި ބަދަލުކޮށް ނަހަދާށެވެ! އަދި، އެކުދިންގެ މުދާތައް، ތިޔަބައިމީހުންގެ މުދަލާއެކު ބޭނުންކޮށް، ކައި ނޫޅޭށެވެ! ހަމަކަށަވަރުން، ބޮޑުވެގެންވާ ފާފައެއް ކަމުގައި އެކަންތައްވިއެވެ.","",""],["₄ سورة النساء","3","وَإِنۡ خِفۡتُمۡ أَلَّا تُقۡسِطُواْ فِي ٱلۡيَتَٰمَىٰ فَٱنكِحُواْ مَا طَابَ لَكُم مِّنَ ٱلنِّسَآءِ مَثۡنَىٰ وَثُلَٰثَ وَرُبَٰعَۖ فَإِنۡ خِفۡتُمۡ أَلَّا تَعۡدِلُواْ فَوَٰحِدَةً أَوۡ مَا مَلَكَتۡ أَيۡمَٰنُكُمۡۚ ذَٰلِكَ أَدۡنَىٰٓ أَلَّا تَعُولُواْ ٣","وإن خفتم ألا تقسطوا في اليتامى فانكحوا ما طاب لكم من النساء مثنى وثلاث ورباع فإن خفتم ألا تعدلوا فواحدة أو ما ملكت أيمانكم ذلك أدنى ألا تعولوا","ޔަތީމުންނާމެދު، ޢަދުލުވެރި ނުވެވޭނެކަމަށް ތިޔަބައިމީހުންނަށް ހީވެ، ބިރުގެންފިނަމަ (އެބަހީ: ތިޔަބައިމީހުންގެ ބެލުމުގެ ދަށުގައިވާ ޔަތީމު އަންހެން ކުދިންނާ ކާވެނިކުރުމުގައި، ޢަދުލުވެރި ނުވެވޭނެކަމަށް ހީވާނަމަ، އެނޫން) އަންހެނުންގެ ތެރެއިން، ތިޔަބައިމީހުން ހިތްރުހޭ ބަޔަކާ ކާވެނިކުރާށެވެ! ދެމީހުނާއެވެ. ނުވަތަ ތިންމީހުނާއެވެ. ނުވަތަ ހަތަރުމީހުނާއެވެ. ފަހެ، ޢަދުލުވެރި ނުވެވޭނެކަމަށް ބިރުގެންފިނަމަ، އެކަކާއެވެ. ނުވަތަ، ތިޔަބައިމީހުންނަށް މިލްކުވެގެންވާ އަޅު އަންހެނުންނާއެވެ. އެގޮތް ތިޔަބައިމީހުން އަނިޔާވެރިނުވުމާ ގާތްކަން ބޮޑެވެ.","",""],["₄ سورة النساء","4","وَءَاتُواْ ٱلنِّسَآءَ صَدُقَٰتِهِنَّ نِحۡلَةٗۚ فَإِن طِبۡنَ لَكُمۡ عَن شَيۡءٖ مِّنۡهُ نَفۡسٗا فَكُلُوهُ هَنِيٓـٔٗا مَّرِيٓـٔٗا ٤","وآتوا النساء صدقاتهن نحلة فإن طبن لكم عن شيء منه نفسا فكلوه هنيئا مريئا","އަންހެނުންނަށް އެކަނބަލުންގެ ރަން، ތިޔަބައިމީހުން ހިތުންރުހުމުންދޭ ދިނުމެއްގެ ގޮތުގައި ދޭށެވެ! އޭގެތެރެއިން އެއްޗެއް އެކަނބަލުން ހިތުންރުހުމުން ތިޔަބައިމީހުންނަށް އަނބުރާ ދީފިނަމަ، ހަލާލު ރަނގަޅު އެއްޗެއްގެ ގޮތުގައި، ތިޔަބައިމީހުން އޭގެ ބޭނުންކުރާށެވެ!","",""],["₄ سورة النساء","5","وَلَا تُؤۡتُواْ ٱلسُّفَهَآءَ أَمۡوَٰلَكُمُ ٱلَّتِي جَعَلَ ٱللَّهُ لَكُمۡ قِيَٰمٗا وَٱرۡزُقُوهُمۡ فِيهَا وَٱكۡسُوهُمۡ وَقُولُواْ لَهُمۡ قَوۡلٗا مَّعۡرُوفٗا ٥","ولا تؤتوا السفهاء أموالكم التي جعل الله لكم قياما وارزقوهم فيها واكسوهم وقولوا لهم قولا معروفا","އަދި، ދޯދިޔާ މީހުންނަށް، (އެބަހީ: ވިޔާނުދާ ޚަރަދު ކޮށް، އިސްރާފު ކޮށް އުޅޭމީހުންގެ އަތަށް) ތިޔަބައިމީހުންގެ އަތުގައިވާ އެއުރެންގެ މުދާތައް ނުދޭށެވެ! އެ މުދަލަކީ، ދިރިއުޅުން ހިފަހައްޓައިދެނިވި ބާރެއްކަމުގައި ﷲ ތިޔަބައިމީހުންނަށް ލައްވާފައިވާ އެއްޗެކެވެ. އަދި، ތިޔަބައިމީހުން އެއިން، އެއުރެންނަށް ކާންދޭށެވެ! އަދި އެއުރެންނަށް އަންނައުނު ދޭށެވެ! އަދި، ތިޔަބައިމީހުން، އެއުރެންނަށް ހެޔޮބަސް ބުނާށެވެ!","",""],["₄ سورة النساء","6","وَٱبۡتَلُواْ ٱلۡيَتَٰمَىٰ حَتَّىٰٓ إِذَا بَلَغُواْ ٱلنِّكَاحَ فَإِنۡ ءَانَسۡتُم مِّنۡهُمۡ رُشۡدٗا فَٱدۡفَعُوٓاْ إِلَيۡهِمۡ أَمۡوَٰلَهُمۡۖ وَلَا تَأۡكُلُوهَآ إِسۡرَافٗا وَبِدَارًا أَن يَكۡبَرُواْۚ وَمَن كَانَ غَنِيّٗا فَلۡيَسۡتَعۡفِفۡۖ وَمَن كَانَ فَقِيرٗا فَلۡيَأۡكُلۡ بِٱلۡمَعۡرُوفِۚ فَإِذَا دَفَعۡتُمۡ إِلَيۡهِمۡ أَمۡوَٰلَهُمۡ فَأَشۡهِدُواْ عَلَيۡهِمۡۚ وَكَفَىٰ بِٱللَّهِ حَسِيبٗا ٦","وابتلوا اليتامى حتى إذا بلغوا النكاح فإن آنستم منهم رشدا فادفعوا إليهم أموالهم ولا تأكلوها إسرافا وبدارا أن يكبروا ومن كان غنيا فليستعفف ومن كان فقيرا فليأكل بالمعروف فإذا دفعتم إليهم أموالهم فأشهدوا عليهم وكفى بالله حسيبا","އަދި، ތިޔަބައިމީހުން ޔަތީމު ކުދިންގެ ގޮތް ބަލާށެވެ! އެކުދިން ކާވެނި ފުރާވަރަށް ދާނދެނެވެ. ފަހެ، (މުދަލާމެދުގައި) ބުއްދި ފުރިހަމަކަން އެއުރެންގެ ކިބައިން ތިޔަބައިމީހުންނަށް ފެނިއްޖެނަމަ، އެއުރެންގެ މުދާތައް އެއުރެންނަށް ދޭށެވެ! އަދި، އިސްރާފުގެ ގޮތުންނާއި، އެކުދިން ބޮޑެތި ވެދާނެތީ (ބިރުން) އަވަސްވެގަނެގެން، ތިޔަބައިމީހުން އެ މުދާ ނުކާށެވެ! މުއްސަންޖަކު ކަމުގައި ވެއްޖެމީހާ، ޢިއްފަތް ތެރި ވާހުށިކަމެވެ! (އެބަހީ: އެ މުދަލުގައި ނުޖެހޭ ހުށިކަމެވެ!) އަދި، ފަގީރަކުކަމުގައި ވެއްޖެމީހާ، ހެޔޮ ރަނގަޅު ގޮތުގައި (އެ މުދަލުން) ކާހުށިކަމެވެ! ފަހެ، އެއުރެންގެ މުދާތައް، ތިޔަބައިމީހުން އެއުރެންނަށް ދޭހިނދު، އެއުރެންގެ މައްޗަށް ތިޔަބައިމީހުން ހެކިކުރާށެވެ! ހިސާބު ބައްލަވަނިވި ކަލަކު ކަމުގައި ﷲ ފުދެއެވެ.","",""],["₄ سورة النساء","7","لِّلرِّجَالِ نَصِيبٞ مِّمَّا تَرَكَ ٱلۡوَٰلِدَانِ وَٱلۡأَقۡرَبُونَ وَلِلنِّسَآءِ نَصِيبٞ مِّمَّا تَرَكَ ٱلۡوَٰلِدَانِ وَٱلۡأَقۡرَبُونَ مِمَّا قَلَّ مِنۡهُ أَوۡ كَثُرَۚ نَصِيبٗا مَّفۡرُوضٗا ٧","للرجال نصيب مما ترك الوالدان والأقربون وللنساء نصيب مما ترك الوالدان والأقربون مما قل منه أو كثر نصيبا مفروضا","މައިންބަފައިންނާއި، ތިމާގެމީހުން ދޫކުޅަ ތަކެތީގެ ތެރެއިން، ފިރިހެނުންނަށް ބަޔެއް ވެއެވެ. އަދި، މައިންބަފައިންނާއި ތިމާގެމީހުން ދޫކުޅަ ތަކެތީގެ ތެރެއިން އަންހެނުންނަށްވެސް ބަޔެއް ވެއެވެ. އެ ދޫކުޅަ ތަކެތީގެ ތެރެއިން މަދު އެއްޗަކުންނާއި، ގިނަ އެއްޗަކުންވެސް ކަނޑައެޅިގެންވާ ބަޔެއްގެ ގޮތުގައެވެ.","",""],["₄ سورة النساء","8","وَإِذَا حَضَرَ ٱلۡقِسۡمَةَ أُوْلُواْ ٱلۡقُرۡبَىٰ وَٱلۡيَتَٰمَىٰ وَٱلۡمَسَٰكِينُ فَٱرۡزُقُوهُم مِّنۡهُ وَقُولُواْ لَهُمۡ قَوۡلٗا مَّعۡرُوفٗا ٨","وإذا حضر القسمة أولو القربى واليتامى والمساكين فارزقوهم منه وقولوا لهم قولا معروفا","(ތަރިކަ މުދާ) ބަހާތަނަށް (އެ މުދަލުން ނުވާ) ގާތްތިމާގެ މީހުންނާއި، ޔަތީމްނާއި، މިސްކީނުން ޙާޒިރުު ވެއްޖެނަމަ، (އެ މުދާ ބެހުމުގެ ކުރިން) އެއުރެންނަށް އެއިން އެތިކޮޅެއް ދޭށެވެ! އަދި، އެއުރެންނަށް ހެޔޮބަސް ބުނާށެވެ!","",""],["₄ سورة النساء","9","وَلۡيَخۡشَ ٱلَّذِينَ لَوۡ تَرَكُواْ مِنۡ خَلۡفِهِمۡ ذُرِّيَّةٗ ضِعَٰفًا خَافُواْ عَلَيۡهِمۡ فَلۡيَتَّقُواْ ٱللَّهَ وَلۡيَقُولُواْ قَوۡلٗا سَدِيدًا ٩","وليخش الذين لو تركوا من خلفهم ذرية ضعافا خافوا عليهم فليتقوا الله وليقولوا قولا سديدا","ނިކަމެތި ދަރިންކޮޅެއް އެއުރެންގެ ފަހަތަށް ދޫކުޅަނަމަ، އެކުދިންގެ މައްޗަށް ބިރުވެތިވާ ފަދައިން، އެއުރެން (ﷲއަށް) ބިރުވެތި ވާހުށިކަމެވެ! އަދި، އެއުރެން ﷲއަށް ތަގުވާވެރިވާހުށިކަމެވެ! އަދި، އިންޞާފުވެރި ސީދާ ބުނުމެއް އެއުރެން ބުނާހުށިކަމެވެ!","",""],["₄ سورة النساء","10","إِنَّ ٱلَّذِينَ يَأۡكُلُونَ أَمۡوَٰلَ ٱلۡيَتَٰمَىٰ ظُلۡمًا إِنَّمَا يَأۡكُلُونَ فِي بُطُونِهِمۡ نَارٗاۖ وَسَيَصۡلَوۡنَ سَعِيرٗا ١٠","إن الذين يأكلون أموال اليتامى ظلما إنما يأكلون في بطونهم نارا وسيصلون سعيرا","ހަމަކަށަވަރުން، އަނިޔާވެރިކަމުގެގޮތުން ޔަތީމުންގެ މުދާ ކައިއުޅޭ މީހުން (ދަންނާށެވެ!) އެއުރެން ކައިއުޅޭކަން ކަށަވަރީ (ނަރަކައިގެ) އަލިފާނެވެ. އަދި، އަނދަ އަނދާ ހުންނަ ނަރަކަޔަކަށް އެއުރެން ނިކަންހުރެ ވަންނާނެތެވެ.","",""],["₄ سورة النساء","11","يُوصِيكُمُ ٱللَّهُ فِيٓ أَوۡلَٰدِكُمۡۖ لِلذَّكَرِ مِثۡلُ حَظِّ ٱلۡأُنثَيَيۡنِۚ فَإِن كُنَّ نِسَآءٗ فَوۡقَ ٱثۡنَتَيۡنِ فَلَهُنَّ ثُلُثَا مَا تَرَكَۖ وَإِن كَانَتۡ وَٰحِدَةٗ فَلَهَا ٱلنِّصۡفُۚ وَلِأَبَوَيۡهِ لِكُلِّ وَٰحِدٖ مِّنۡهُمَا ٱلسُّدُسُ مِمَّا تَرَكَ إِن كَانَ لَهُۥ وَلَدٞۚ فَإِن لَّمۡ يَكُن لَّهُۥ وَلَدٞ وَوَرِثَهُۥٓ أَبَوَاهُ فَلِأُمِّهِ ٱلثُّلُثُۚ فَإِن كَانَ لَهُۥٓ إِخۡوَةٞ فَلِأُمِّهِ ٱلسُّدُسُۚ مِنۢ بَعۡدِ وَصِيَّةٖ يُوصِي بِهَآ أَوۡ دَيۡنٍۗ ءَابَآؤُكُمۡ وَأَبۡنَآؤُكُمۡ لَا تَدۡرُونَ أَيُّهُمۡ أَقۡرَبُ لَكُمۡ نَفۡعٗاۚ فَرِيضَةٗ مِّنَ ٱللَّهِۗ إِنَّ ٱللَّهَ كَانَ عَلِيمًا حَكِيمٗا ١١","يوصيكم الله في أولادكم للذكر مثل حظ الأنثيين فإن كن نساء فوق اثنتين فلهن ثلثا ما ترك وإن كانت واحدة فلها النصف ولأبويه لكل واحد منهما السدس مما ترك إن كان له ولد فإن لم يكن له ولد وورثه أبواه فلأمه الثلث فإن كان له إخوة فلأمه السدس من بعد وصية يوصي بها أو دين آباؤكم وأبناؤكم لا تدرون أيهم أقرب لكم نفعا فريضة من الله إن الله كان عليما حكيما","ތިޔަބައިމީހުންގެ ދަރިންނާމެދު، ﷲ ތިޔަބައިމީހުންނަށް އަންގަވަތެވެ. އަންހެން ދެ ދަރިންގެ ބަޔާ އެއްފަދަ ބަޔެއް ފިރިހެން ދަރިޔަކަށް ވެއެވެ. އެ ދަރިންނަކީ ދޭކަށްވުރެ މަތީ އަދަދެއްގެ އަންހެނުން ކަމުގައިވާނަމަ، މަރުވި މީހާ ދޫކުރި މުދަލުގެ ތިންބައިކުޅަ ދެބައި އެކަނބަލުންނަށެވެ. އަދި، އެއީ އެންމެ އަންހެން ދަރިޔަކު ކަމުގައި ވެއްޖެނަމަ، ފަހެ، އެކަނބުލޭގެޔަށް ދެބައިކުޅަ އެއްބަޔެވެ. އަދި، މަރުވިމީހާގެ ދަރިޔަކު ހުރިނަމަ، އޭނާގެ މަންމަޔާއި، ބައްޕަޔާއި، ދެމީހުންކުރެ ކޮންމެ މީހަކަށްމެ، އެ މަރުވި މީހާ ދޫކުޅަ މުދަލުގެ ހަބައިކުޅަ އެއްބަޔެވެ. ފަހެ، އޭނާޔަށް ދަރިޔަކު ނުވާނަމަ، އަދި، (ހަމައެކަނި) އޭނާގެ މަންމަޔާއި ބައްޕަޔަށް ވާރުތައަރާނަމަ، ފަހެ، އޭނާގެ މަންމަޔަށް ތިންބައިކުޅަ އެއްބަޔެވެ. (ދެންހުރި އެއްޗެއް ބައްޕަޔަށެވެ.) ފަހެ، އެ މަރުވި މީހާޔަށް އަޚްނާއި، އުޚްތުން (އެކަކަށްވުރެ ގިނައިން) ތިބިނަމަ، ފަހެ، އޭނާގެ މަންމަޔަށް ހަބައިކުޅަ އެއްބަޔެވެ. ކުރާ ވަސިއްޔަތެއްވާނަމަ، އެ ވަސިއްޔަތެއް ތަންފީޛުކުރުމަށްފަހުގައެވެ. ނުވަތަ، ދަރަންޏެއް ވާނަމަ، އެ ދަރަންޏެއް އަދާކުރުމަށް ފަހުގައެވެ. ތިޔަބައިމީހުންގެ މައިންބަފައިންނާއި، ތިޔަބައިމީހުންގެ ދަރިންކުރެ މަންފާކުރުމުގެ ގޮތުން ތިޔަބައިމީހުންނާ ގާތްކަންބޮޑީ ކޮންބަޔެއްކަން ތިޔަބައިމީހުންނަކަށް ނޭނގެއެވެ. (ބަޔާންވެ ދިޔަގޮތަށް މުދާ ބެހުންއޮތީ) ﷲގެ ހަޒުރަތުން ކަނޑައަޅުއްވައި އަންގަވާފައިވާ ފަރުޟެއްގެ ގޮތުގައެވެ. ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₄ سورة النساء","12","۞وَلَكُمۡ نِصۡفُ مَا تَرَكَ أَزۡوَٰجُكُمۡ إِن لَّمۡ يَكُن لَّهُنَّ وَلَدٞۚ فَإِن كَانَ لَهُنَّ وَلَدٞ فَلَكُمُ ٱلرُّبُعُ مِمَّا تَرَكۡنَۚ مِنۢ بَعۡدِ وَصِيَّةٖ يُوصِينَ بِهَآ أَوۡ دَيۡنٖۚ وَلَهُنَّ ٱلرُّبُعُ مِمَّا تَرَكۡتُمۡ إِن لَّمۡ يَكُن لَّكُمۡ وَلَدٞۚ فَإِن كَانَ لَكُمۡ وَلَدٞ فَلَهُنَّ ٱلثُّمُنُ مِمَّا تَرَكۡتُمۚ مِّنۢ بَعۡدِ وَصِيَّةٖ تُوصُونَ بِهَآ أَوۡ دَيۡنٖۗ وَإِن كَانَ رَجُلٞ يُورَثُ كَلَٰلَةً أَوِ ٱمۡرَأَةٞ وَلَهُۥٓ أَخٌ أَوۡ أُخۡتٞ فَلِكُلِّ وَٰحِدٖ مِّنۡهُمَا ٱلسُّدُسُۚ فَإِن كَانُوٓاْ أَكۡثَرَ مِن ذَٰلِكَ فَهُمۡ شُرَكَآءُ فِي ٱلثُّلُثِۚ مِنۢ بَعۡدِ وَصِيَّةٖ يُوصَىٰ بِهَآ أَوۡ دَيۡنٍ غَيۡرَ مُضَآرّٖۚ وَصِيَّةٗ مِّنَ ٱللَّهِۗ وَٱللَّهُ عَلِيمٌ حَلِيمٞ ١٢","ولكم نصف ما ترك أزواجكم إن لم يكن لهن ولد فإن كان لهن ولد فلكم الربع مما تركن من بعد وصية يوصين بها أو دين ولهن الربع مما تركتم إن لم يكن لكم ولد فإن كان لكم ولد فلهن الثمن مما تركتم من بعد وصية توصون بها أو دين وإن كان رجل يورث كلالة أو امرأة وله أخ أو أخت فلكل واحد منهما السدس فإن كانوا أكثر من ذلك فهم شركاء في الثلث من بعد وصية يوصى بها أو دين غير مضار وصية من الله والله عليم حليم","ތިޔަބައިމީހުންގެ އަނބިން ދޫކުޅަ މުދަލެއްގެ ދެބައިކުޅަ އެއްބައި ތިޔަބައިމީހުންނަށެވެ. އެއީ، އެކަނބަލުންނަށް ދަރިޔަކު ނުވާނަމައެވެ. ފަހެ، އެކަނބަލުންނަށް ދަރިޔަކުވާނަމަ، އެކަނބަލުން ދޫކުޅަ މުދަލެއްގެ ހަތަރުބައިކުޅަ އެއްބައި ތިޔަބައިމީހުންނަށެވެ. އެއީ، އެކަނބަލުން ކުރާ ވަސިއްޔަތެއްވާނަމަ، އެ ވަސިއްޔަތެއް ތަންފީޛުކުރުމަށްފަހު، ނުވަތަ ދަރަންޏެއް ވާނަމަ، އެ ދަރަންޏެއް އަދާކުރުމަށްފަހުގައެވެ. އަދި، ތިޔަބައިމީހުންނަށް ދަރިޔަކު ނުވާނަމަ، ތިޔަބައިމީހުން ދޫކުޅަ މުދަލެއްގެ ހަތަރުބައިކުޅަ އެއްބައި އެކަނބަލުންނަށެވެ. ފަހެ، ތިޔަބައިމީހުންނަށް ދަރިޔަކުވާނަމަ، ތިޔަބައިމީހުން ދޫކުޅަ މުދަލެއްގެ އަށްބައިކުޅަ އެއްބައި އެކަނބަލުންނަށެވެ. އެއީ، ތިޔަބައިމީހުންކުރާ ވަސިއްޔަތެއްވާނަމަ، އެ ވަސިއްޔަތެއް ތަންފީޛުކުރުމަށްފަހު، ނުވަތަ، ދަރަންޏެއްވާނަމަ، އެ ދަރަންޏެއް އަދާކުރުމަށްފަހުގައެވެ. ކަލާލަތުގެ ގޮތުން (އެބަހީ: އަޞްލެއް ފަރުޢެއްނެތި) ފިރިހެނަކު ނުވަތަ އަންހެނަކު (ކިބައިން) ވާރުތަކުރެވޭނަމަ، އަދި، އޭނާޔަށް އަޚަކު ނުވަތަ އުޚްތަކު ހުރިނަމަ، ފަހެ، އެއިން ކޮންމެ މީހަކަށް ހަބައިކުޅަ އެއްބަޔެވެ. ފަހެ، އެ އަޚްނާއި އުޚްތުން އެއަށްވުރެ ގިނަނަމަ، އެއުރެންވަނީ ތިންބައިކުޅަ އެއްބައިގައި (ހަމަހަމަޔަށް) ބައިވެރިވެގެންނެވެ. އެއީ، (ވާރުތަވެރިންނަށް) ގެއްލުން ނުދޭގޮތުގައި ކުރާ ވަސިއްޔަތެއްވާނަމަ، އެ ވަސިއްޔަތެއް ތަންފީޛުކުރުމަށްފަހު، ނުވަތަ، ދަރަންޏެއްވާނަމަ، އެ ދަރަންޏެއް އަދާކުރުމަށްފަހުގައެވެ. ﷲގެ ހަޒުރަތުން އަންގަވާފައިވާ އެންގެވުމެއްގެ ގޮތުގައެވެ. ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ ހަލީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₄ سورة النساء","13","تِلۡكَ حُدُودُ ٱللَّهِۚ وَمَن يُطِعِ ٱللَّهَ وَرَسُولَهُۥ يُدۡخِلۡهُ جَنَّـٰتٖ تَجۡرِي مِن تَحۡتِهَا ٱلۡأَنۡهَٰرُ خَٰلِدِينَ فِيهَاۚ وَذَٰلِكَ ٱلۡفَوۡزُ ٱلۡعَظِيمُ ١٣","تلك حدود الله ومن يطع الله ورسوله يدخله جنات تجري من تحتها الأنهار خالدين فيها وذلك الفوز العظيم","އެއީ، ﷲ ކަނޑައަޅުއްވައި އަންގަވާފައިވާ އިންތަކެވެ. ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް ކިޔަމަންތެރިވާ މީހާ، އެތާނގެ ދަށުން ފެންއާރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކަށް ވައްދަވާނެތެވެ. އެތާނގައި، އެއުރެން ދެމިތިބެނިވި ގޮތުގައެވެ. ބޮޑުވެގެންވާ ނަސީބު ލިބުމަކީ އެއީއެވެ.","",""],["₄ سورة النساء","14","وَمَن يَعۡصِ ٱللَّهَ وَرَسُولَهُۥ وَيَتَعَدَّ حُدُودَهُۥ يُدۡخِلۡهُ نَارًا خَٰلِدٗا فِيهَا وَلَهُۥ عَذَابٞ مُّهِينٞ ١٤","ومن يعص الله ورسوله ويتعد حدوده يدخله نارا خالدا فيها وله عذاب مهين","އަދި، ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް އުރެދި، އެކަލާނގެ ކަނޑައަޅުއްވާފައިވާ އިންތައް ފަހަނަޅައިދާމީހަކު، ނަރަކަޔަށް ވައްދަވާނެތެވެ. އެތާނގައި އެމީހަކު ދެމިހުންނަނިވި ގޮތުގައެވެ. އަދި، އެމީހަކަށް އިހާނަތްތެރިކަން ދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["₄ سورة النساء","15","وَٱلَّـٰتِي يَأۡتِينَ ٱلۡفَٰحِشَةَ مِن نِّسَآئِكُمۡ فَٱسۡتَشۡهِدُواْ عَلَيۡهِنَّ أَرۡبَعَةٗ مِّنكُمۡۖ فَإِن شَهِدُواْ فَأَمۡسِكُوهُنَّ فِي ٱلۡبُيُوتِ حَتَّىٰ يَتَوَفَّىٰهُنَّ ٱلۡمَوۡتُ أَوۡ يَجۡعَلَ ٱللَّهُ لَهُنَّ سَبِيلٗا ١٥","واللاتي يأتين الفاحشة من نسائكم فاستشهدوا عليهن أربعة منكم فإن شهدوا فأمسكوهن في البيوت حتى يتوفاهن الموت أو يجعل الله لهن سبيلا","ތިޔަބައިމީހުންގެ އަންހެނުންކުރެ ހުތުރުކަން ބޮޑުވެގެންވާ ފާފަ ގެނެސްގަންނަ މީހުންނާމެދު، (އެބަހީ: ޒިނޭކުރާ މީހުންނާމެދު) ތިޔަބައިމީހުންގެ ތެރެއިން ހަތަރު ހެކިން، އެކަނބަލުންގެ މައްޗަށް ހެކިކުރާށެވެ! ފަހެ، އެއުރެން ހެކިދީފިނަމަ، މަރު، އެކަނބަލުން އަތުލައިފުމަށް ދާނދެން (އެބަހީ: މަރުވެއްޖައުމަށް ދާނދެން) ނުވަތަ، އެކަނބަލުންނަށް ﷲ މަގެއް ދައްކަވައިފުމަށް ދާނދެން، ގޭގޭގައި އެކަނބަލުން ބަންދުކުރާށެވެ! (އިތުރު ބަޔާނެއް: މަގެއް ދެއްކެވުމޭ އޮތްބަސްފުޅުގެ މުރާދަކީ، އެކަނބަލުންނަށް ދޭނެ އުގޫބާތެއް ކަނޑައަޅުއްވައި އެންގެވުމެވެ. އެކަންއޮތީ ސޫރަތުއްނޫރުގެ ދެވަނަ އާޔަތުން އަންގަވާފައެވެ.)","",""],["₄ سورة النساء","16","وَٱلَّذَانِ يَأۡتِيَٰنِهَا مِنكُمۡ فَـَٔاذُوهُمَاۖ فَإِن تَابَا وَأَصۡلَحَا فَأَعۡرِضُواْ عَنۡهُمَآۗ إِنَّ ٱللَّهَ كَانَ تَوَّابٗا رَّحِيمًا ١٦","واللذان يأتيانها منكم فآذوهما فإن تابا وأصلحا فأعرضوا عنهما إن الله كان توابا رحيما","އަދި، ތިޔަބައިމީހުންގެ ތެރެއިން ފާޙީޝް ކަންތައް ގެނެސްގަންނަ ދެމީހުންނަށް ތިޔަބައިމީހުން އަދަބުދޭށެވެ! ފަހެ، އެދެމީހުން ތައުބާވެ، އަދި، އެއުރެންގެ ޢަމަލު އިސްލާހު ކޮށްފިނަމަ، އެ ދެމީހުންގެ ކިބައިން ދުރުވެގަންނާށެވެ! (އެބަހީ: އަދަބުދިނުން ހުއްޓައިލާށެވެ!) ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ތައުބާ ގަބޫލުކުރައްވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₄ سورة النساء","17","إِنَّمَا ٱلتَّوۡبَةُ عَلَى ٱللَّهِ لِلَّذِينَ يَعۡمَلُونَ ٱلسُّوٓءَ بِجَهَٰلَةٖ ثُمَّ يَتُوبُونَ مِن قَرِيبٖ فَأُوْلَـٰٓئِكَ يَتُوبُ ٱللَّهُ عَلَيۡهِمۡۗ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمٗا ١٧","إنما التوبة على الله للذين يعملون السوء بجهالة ثم يتوبون من قريب فأولئك يتوب الله عليهم وكان الله عليما حكيما","ތައުބާ ލެއްވުން ﷲގެ ހަޒުރަތުން އޮތްކަން ކަށަވަރީ، ނޭނގިތިބުމާއެކު ނުބައިކަންތައްކޮށް، ދެން، އެކަންތައް ކުރުމާ ގާތުގައި (ލަސްނުކޮށް) ތައުބާވެ އުޅޭމީހުންނަށެވެ. ފަހެ، ﷲ، އެއުރެންގެ މައްޗަށް ތައުބާ ލައްވަތެވެ. އަދި، މޮޅަށް ދެނެވޮޑިގެންވާ ޙަކީމްވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","18","وَلَيۡسَتِ ٱلتَّوۡبَةُ لِلَّذِينَ يَعۡمَلُونَ ٱلسَّيِّـَٔاتِ حَتَّىٰٓ إِذَا حَضَرَ أَحَدَهُمُ ٱلۡمَوۡتُ قَالَ إِنِّي تُبۡتُ ٱلۡـَٰٔنَ وَلَا ٱلَّذِينَ يَمُوتُونَ وَهُمۡ كُفَّارٌۚ أُوْلَـٰٓئِكَ أَعۡتَدۡنَا لَهُمۡ عَذَابًا أَلِيمٗا ١٨","وليست التوبة للذين يعملون السيئات حتى إذا حضر أحدهم الموت قال إني تبت الآن ولا الذين يموتون وهم كفار أولئك أعتدنا لهم عذابا أليما","އަދި، ނުބައިކަންތައް ކޮށްކޮށް ތިއްބާ އެއިންމީހެއްގެ ގާތަށް މަރު އައިސް ޙާޒިރުު ވެއްޖެނަމަ، އެހިނދު ތިމަން މިހާރު ތައުބާ ވެއްޖައީމޭ ބުނާ މީހުންނާއި، ކާފިރުން ކަމުގައި ތިބެ މަރުވާ މީހުންނަކަށް ތައުބާ ލެއްވުމެއްނެތެވެ. އެއުރެންނަށްޓަކައި ވޭންދެނިވި އަޒާބު ތިމަންރަސްކަލާނގެ ތައްޔާރުކުރެއްވީމެވެ.","",""],["₄ سورة النساء","19","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا يَحِلُّ لَكُمۡ أَن تَرِثُواْ ٱلنِّسَآءَ كَرۡهٗاۖ وَلَا تَعۡضُلُوهُنَّ لِتَذۡهَبُواْ بِبَعۡضِ مَآ ءَاتَيۡتُمُوهُنَّ إِلَّآ أَن يَأۡتِينَ بِفَٰحِشَةٖ مُّبَيِّنَةٖۚ وَعَاشِرُوهُنَّ بِٱلۡمَعۡرُوفِۚ فَإِن كَرِهۡتُمُوهُنَّ فَعَسَىٰٓ أَن تَكۡرَهُواْ شَيۡـٔٗا وَيَجۡعَلَ ٱللَّهُ فِيهِ خَيۡرٗا كَثِيرٗا ١٩","يا أيها الذين آمنوا لا يحل لكم أن ترثوا النساء كرها ولا تعضلوهن لتذهبوا ببعض ما آتيتموهن إلا أن يأتين بفاحشة مبينة وعاشروهن بالمعروف فإن كرهتموهن فعسى أن تكرهوا شيئا ويجعل الله فيه خيرا كثيرا","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ނުރުހުމުގައި އަންހެނުން ވާރުތަކޮށް ގަތުމަކީ، ތިޔަބައިމީހުންނަށް ހަލާލު ވެގެންވާ ކަމެއްނޫނެވެ. އަދި، ފާޅުވެގެންހުރި ހުތުރުކަން ބޮޑުވެގެންވާ ފާފައެއް އެކަނބަލުން ގެނެސްގަންނަ ކަމުގައިވަންޏާ މެނުވީ އެކަނބަލުންނަށް ތިޔަބައިމީހުން ދީފައިވާ ތަކެތީގެ ތެރެއިން ބަޔެއް އަތުލައިގަތުމަށްޓަކައި އެކަނބަލުންނަށް ދަތިނުކުރާށެވެ! އަދި، ހެޔޮގޮތުގައި އެކަނބަލުންނާއެކު އުޅޭށެވެ! ތިޔަބައިމީހުން އެކަނބަލުންނާ ނުރުހުންތެރި ވެއްޖެނަމަ (ދަންނާށެވެ!) ބައެއްފަހަރަށް ތިޔަބައިމީހުން އެއްޗަކަށް ނުރުހުން ވެދާނެއެވެ. އަދި، އެ އެއްޗެއްގައި ﷲ ގިނަވެގެންވާ ހެޔޮކަން ލައްވައިފާނެތެވެ.","",""],["₄ سورة النساء","20","وَإِنۡ أَرَدتُّمُ ٱسۡتِبۡدَالَ زَوۡجٖ مَّكَانَ زَوۡجٖ وَءَاتَيۡتُمۡ إِحۡدَىٰهُنَّ قِنطَارٗا فَلَا تَأۡخُذُواْ مِنۡهُ شَيۡـًٔاۚ أَتَأۡخُذُونَهُۥ بُهۡتَٰنٗا وَإِثۡمٗا مُّبِينٗا ٢٠","وإن أردتم استبدال زوج مكان زوج وآتيتم إحداهن قنطارا فلا تأخذوا منه شيئا أتأخذونه بهتانا وإثما مبينا","ތިޔަބައިމީހުން އެއް އަނތްބެއްގެ ޖާގަޔަށް އެހެން އަނތްބަކު ބަދަލުކުރަން އެދޭނަމަ، (އެބަހީ: އެކަކު ވަރިކޮށްފައި އަނެކަކާ އިންނަން ގަސްދު ކޮށްފިނަމަ) އަދި، އެ އަނތްބަށް (ރަނުގެ ގޮތުން) ކިތަންމެ ގިނަ މުދާތަކެއް ދީފައިވިޔަސް އޭގެތެރެއިން އެއްޗެއް ތިޔަބައިމީހުން އަތުނުލާ ހުށިކަމެވެ. ބާތިލު ގޮތުގައި، އަދި، ފާޅުވެގެންވާ ފާފައެއް ކުރުމުގެ ގޮތުގައި، ތިޔަބައިމީހުން އެތަކެތި އަތުލަނީހެއްޔެވެ؟","",""],["₄ سورة النساء","21","وَكَيۡفَ تَأۡخُذُونَهُۥ وَقَدۡ أَفۡضَىٰ بَعۡضُكُمۡ إِلَىٰ بَعۡضٖ وَأَخَذۡنَ مِنكُم مِّيثَٰقًا غَلِيظٗا ٢١","وكيف تأخذونه وقد أفضى بعضكم إلى بعض وأخذن منكم ميثاقا غليظا","ތިޔަބައިމީހުން އެތަކެތި އަތުލަނީ ކޮންފަދަޔަކުން ހެއްޔެވެ؟ ތިޔަބައިމީހުންގެ ތެރެއިން އެއްބަޔަކުވަނީ އަނެއްބަޔަކާއެކު އެއްދާންކޮށްފައެވެ. އަދި، އެކަނބަލުންވަނީ، ތިޔަބައިމީހުންގެ ކިބައިން ގަދަވެގެންވާ އަހުދު ހިފާފައެވެ.","",""],["₄ سورة النساء","22","وَلَا تَنكِحُواْ مَا نَكَحَ ءَابَآؤُكُم مِّنَ ٱلنِّسَآءِ إِلَّا مَا قَدۡ سَلَفَۚ إِنَّهُۥ كَانَ فَٰحِشَةٗ وَمَقۡتٗا وَسَآءَ سَبِيلًا ٢٢","ولا تنكحوا ما نكح آباؤكم من النساء إلا ما قد سلف إنه كان فاحشة ومقتا وساء سبيلا","އަންހެނުންގެ ތެރެއިން ތިޔަބައިމީހުންގެ ބަފައިން ކާވެނިކުޅަ އަންހެނަކާ، ތިޔަބައިމީހުން ކާވެނި ނުކުރާހުށިކަމެވެ! އިސްވެދިޔަތާނގައި މެނުވީއެވެ. (އެބަހީ: ޖާހިލީ ޒަމާނުގައި ހިނގާދިޔަ ކަންތައްވަނީ އަފޫކުރައްވާފައެވެ.) ހަމަކަށަވަރުން، އެކަމަކީ، ހުތުރުކަންބޮޑު ފާފައެއް ކަމުގައްޔާއި، އަދި، ނުރުއްސަވާ ކަމެއްކަމުގައިވިއެވެ. އަދި އެއީ، ހާދަހާ ނުބައިވެގެންވާ މަގެކެވެ.","",""],["₄ سورة النساء","23","حُرِّمَتۡ عَلَيۡكُمۡ أُمَّهَٰتُكُمۡ وَبَنَاتُكُمۡ وَأَخَوَٰتُكُمۡ وَعَمَّـٰتُكُمۡ وَخَٰلَٰتُكُمۡ وَبَنَاتُ ٱلۡأَخِ وَبَنَاتُ ٱلۡأُخۡتِ وَأُمَّهَٰتُكُمُ ٱلَّـٰتِيٓ أَرۡضَعۡنَكُمۡ وَأَخَوَٰتُكُم مِّنَ ٱلرَّضَٰعَةِ وَأُمَّهَٰتُ نِسَآئِكُمۡ وَرَبَـٰٓئِبُكُمُ ٱلَّـٰتِي فِي حُجُورِكُم مِّن نِّسَآئِكُمُ ٱلَّـٰتِي دَخَلۡتُم بِهِنَّ فَإِن لَّمۡ تَكُونُواْ دَخَلۡتُم بِهِنَّ فَلَا جُنَاحَ عَلَيۡكُمۡ وَحَلَـٰٓئِلُ أَبۡنَآئِكُمُ ٱلَّذِينَ مِنۡ أَصۡلَٰبِكُمۡ وَأَن تَجۡمَعُواْ بَيۡنَ ٱلۡأُخۡتَيۡنِ إِلَّا مَا قَدۡ سَلَفَۗ إِنَّ ٱللَّهَ كَانَ غَفُورٗا رَّحِيمٗا ٢٣","حرمت عليكم أمهاتكم وبناتكم وأخواتكم وعماتكم وخالاتكم وبنات الأخ وبنات الأخت وأمهاتكم اللاتي أرضعنكم وأخواتكم من الرضاعة وأمهات نسائكم وربائبكم اللاتي في حجوركم من نسائكم اللاتي دخلتم بهن فإن لم تكونوا دخلتم بهن فلا جناح عليكم وحلائل أبنائكم الذين من أصلابكم وأن تجمعوا بين الأختين إلا ما قد سلف إن الله كان غفورا رحيما","ތިޔަބައިމީހުންގެ މައިންނާއި، އަންހެން ދަރިންނާއި، އުޚްތްނާއި، ބަފައިފުށުގެ ބޮޑުދައިތައިންނާއި، މައިފުށުގެ ބޮޑުދައިތައިންނާއި، އަޚުގެ އަންހެން ދަރިންނާއި، އުޚްތުގެ އަންހެން ދަރިންނާއި، ތިޔަބައިމީހުންނަށް ކިރުދިން މައިންނާއި، ކިރުބުއިމުގެ ގޮތުން ތިޔަބައިމީހުންގެ އުޚްތްނާއި، ތިޔަބައިމީހުންގެ އަނބިންގެ މައިންނާއި، ތިޔަބައިމީހުން އެކަނބަލުންގެ ގާތުގައި ރޭކޮށްފައިވާ އަނބިންގެ ފަރާތުން އައިސް ތިޔަބައިމީހުންގެ އުނގުގައިވާ، (އެބަހީ: ބެލުމުގެ ދަށުގައިވާ) ތިޔަބައިމީހުންގެ ދޮންދަރިންނާއި، (މިމީސްމީހުންނާ) ކާވެނިކުރުން ހަރާމްކުރެއްވިއެވެ. އެކަނބަލުންގެ ގާތުގައި ތިޔަބައިމީހުން ރޭކޮށްފައިނުވާ އަނބިންގެ އަންހެންދަރިންނާ ކާވެނިކުރުމަކުން، ފަހެ، ތިޔަބައިމީހުންގެ މައްޗަކަށް ކުށެއްނެތެވެ. އަދި، ތިޔަބައިމީހުންގެ ބުރިކަށިތަކުން އުފެދިފައިވާ ތިޔަބައިމީހުންގެ އުފަންދަރިން އިން މީހުންވެސް ހަރާމްކުރެއްވިއެވެ. އަދި، ވޭތުވެދިޔަ ޒަމާނުގައި މެނުވީ ދެ އުޚްތުން ދެމެދު އެއްކުރުން (އެބަހީ: އެއްފަހަރާ ދެ އުޚްތުންނާ އިނުން) ވެސް ހަރާމްކުރެއްވިއެވެ. ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެ ކަމުގައިވެއެވެ.","",""],["₄ سورة النساء","24","۞وَٱلۡمُحۡصَنَٰتُ مِنَ ٱلنِّسَآءِ إِلَّا مَا مَلَكَتۡ أَيۡمَٰنُكُمۡۖ كِتَٰبَ ٱللَّهِ عَلَيۡكُمۡۚ وَأُحِلَّ لَكُم مَّا وَرَآءَ ذَٰلِكُمۡ أَن تَبۡتَغُواْ بِأَمۡوَٰلِكُم مُّحۡصِنِينَ غَيۡرَ مُسَٰفِحِينَۚ فَمَا ٱسۡتَمۡتَعۡتُم بِهِۦ مِنۡهُنَّ فَـَٔاتُوهُنَّ أُجُورَهُنَّ فَرِيضَةٗۚ وَلَا جُنَاحَ عَلَيۡكُمۡ فِيمَا تَرَٰضَيۡتُم بِهِۦ مِنۢ بَعۡدِ ٱلۡفَرِيضَةِۚ إِنَّ ٱللَّهَ كَانَ عَلِيمًا حَكِيمٗا ٢٤","والمحصنات من النساء إلا ما ملكت أيمانكم كتاب الله عليكم وأحل لكم ما وراء ذلكم أن تبتغوا بأموالكم محصنين غير مسافحين فما استمتعتم به منهن فآتوهن أجورهن فريضة ولا جناح عليكم فيما تراضيتم به من بعد الفريضة إن الله كان عليما حكيما","ތިޔަބައިމީހުންނަށް މިލްކުވެގެންވާ އަޅު އަންހެނުން ފިޔަވައި، އަންހެނުންގެ ތެރެއިން ކާވެނީގެ ރައްކާތެރިކަން ލިބި (މީހުންނާ އިނދެގެން) ތިބި އަންހެނުންވެސް ތިޔަބައިމީހުންގެ މައްޗަށް ހަރާމްކުރެއްވިއެވެ. (އެއީ) ﷲ ތިޔަބައިމީހުންގެ މައްޗަށް ކަނޑައަޅުއްވައި ލިޔުއްވާފައިވާ ގޮތެވެ. ކާވެނީގެ ރައްކާތެރިކަން ލިބޭގޮތުގައި، އަދި، ޒިނޭނުކުރާ ގޮތުގައި، ތިޔަބައިމީހުންގެ މުދަލުން ކާވެނީގެ ރަން ދީގެން، އެނޫން އަންހެނުންނާ އިނުން، ތިޔަބައިމީހުންނަށް ހުއްދަކުރެއްވިއެވެ. ފަހެ، އެކަނބަލުންގެ ތެރެއިން ތިޔަބައިމީހުން ކާވެނިކޮށް އެކަމުގެ އުފާ ތިޔަބައިމީހުން އެބަޔެއްގެ ކިބައިން ލިބިގަތް ބަޔަކަށް ރަނުގެ ގޮތުގައި އެކަނބަލުންނަށް ކަނޑައަޅުއްވާފައިވާ އުޖޫރަ ތިޔަބައިމީހުން އެކަނބަލުންނަށް ދޭށެވެ! ރަން ކަނޑައެޅުމަށްފަހު، ތިޔަބައިމީހުންގެ ދެފަރާތް ރުހި އެއްބަސްވީ ގޮތަކާމެދު، ތިޔަބައިމީހުންގެ މައްޗަކަށް ކުށެއްނެތެވެ. ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ ޙަކީމްވަންތަ ރަސްކަލާނގެ ކަމުގައިވެއެވެ.","",""],["₄ سورة النساء","25","وَمَن لَّمۡ يَسۡتَطِعۡ مِنكُمۡ طَوۡلًا أَن يَنكِحَ ٱلۡمُحۡصَنَٰتِ ٱلۡمُؤۡمِنَٰتِ فَمِن مَّا مَلَكَتۡ أَيۡمَٰنُكُم مِّن فَتَيَٰتِكُمُ ٱلۡمُؤۡمِنَٰتِۚ وَٱللَّهُ أَعۡلَمُ بِإِيمَٰنِكُمۚ بَعۡضُكُم مِّنۢ بَعۡضٖۚ فَٱنكِحُوهُنَّ بِإِذۡنِ أَهۡلِهِنَّ وَءَاتُوهُنَّ أُجُورَهُنَّ بِٱلۡمَعۡرُوفِ مُحۡصَنَٰتٍ غَيۡرَ مُسَٰفِحَٰتٖ وَلَا مُتَّخِذَٰتِ أَخۡدَانٖۚ فَإِذَآ أُحۡصِنَّ فَإِنۡ أَتَيۡنَ بِفَٰحِشَةٖ فَعَلَيۡهِنَّ نِصۡفُ مَا عَلَى ٱلۡمُحۡصَنَٰتِ مِنَ ٱلۡعَذَابِۚ ذَٰلِكَ لِمَنۡ خَشِيَ ٱلۡعَنَتَ مِنكُمۡۚ وَأَن تَصۡبِرُواْ خَيۡرٞ لَّكُمۡۗ وَٱللَّهُ غَفُورٞ رَّحِيمٞ ٢٥","ومن لم يستطع منكم طولا أن ينكح المحصنات المؤمنات فمن ما ملكت أيمانكم من فتياتكم المؤمنات والله أعلم بإيمانكم بعضكم من بعض فانكحوهن بإذن أهلهن وآتوهن أجورهن بالمعروف محصنات غير مسافحات ولا متخذات أخدان فإذا أحصن فإن أتين بفاحشة فعليهن نصف ما على المحصنات من العذاب ذلك لمن خشي العنت منكم وأن تصبروا خير لكم والله غفور رحيم","އީމާން ވެގެންތިބި މިނިވަން އަންހެނުންނާ ކާވެނިކުރުމަށް، ތިޔަބައިމީހުންގެ ތެރެއިން އަތްމަތި ތަނަވަސްކަމުގެ ގޮތުން ކުޅަދާނަނުވި މީހާ، ތިޔަބައިމީހުންގެ އީމާން ވެގެންތިބި އަންހެންކުދިންކުރެ، ތިޔަބައިމީހުންނަށް މިލްކުވެގެންވާ އަޅުއަންހެނުންގެ ތެރެއިން މީހުންނާ، ކާވެނިކުރުން ހުށްޓެވެ. ތިޔަބައިމީހުންގެ އީމާން ކަން ހުރިގޮތް ﷲ ދެނެވޮޑިގަތުން ބޮޑެވެ. ތިޔަބައިމީހުންގެ އެއްބަޔަކުވަނީ އަނެއްބަޔެއްގެ ތެރެއިންނެވެ. (އެބަހީ: ދީންގެ ގޮތުން ތިޔަބައިމީހުންނެކޭ، އެ އަޅުއަންހެނުންނެކޭ އެއްގޮތެވެ.) ފަހެ، އެކަނބަލުންގެ ސާހިބުންގެ އިޛުނާއެކު، އެކަނބަލުންނާ ތިޔަބައިމީހުން ކާވެނިކުރާށެވެ! އަދި، އެކަނބަލުންގެ ރަން، ހިތްހެޔޮކަމާއެކު ހެޔޮގޮތުގައި އެކަނބަލުންނަށް ދޭށެވެ! ކާވެނީގެ ރައްކާތެރިކަންލިބި، އެކަނބަލުން ޢިއްފަތް ތެރިވެގެންވާ ގޮތުގައެވެ. ޒިނޭކުރާ ގޮތުގައެއް ނޫނެވެ. އަދި، ވަންހަނާގޮތުގައި ޒިނޭކުރާ އެކުވެރިން ގެންގުޅޭ ގޮތުގައެއްވެސް ނޫނެވެ. ފަހެ، އެކަނބަލުން ކާވެނިކުރުމަށްފަހު، ހުތުރުކަން ބޮޑުވެގެންވާ ފާފަޔެއް ގެނެސްގެންފިނަމަ، (އެބަހީ: ޒިނޭކޮށްފިނަމަ) މިނިވަން އަންހެނުންގެ މައްޗަށް އޮތް އަދަބުގެ ދެބައިކުޅަ އެއްބައި އެކަނބަލުންގެ މައްޗަށް ހުށްޓެވެ. އެކަން، (އެބަހީ: އަޅުއަންހެނުންނާ ކާވެނިކުރުން) އޮތީ ތިޔަބައިމީހުންގެ ތެރެއިން ޒިނޭކުރެވިދާނެކަމަށް ބިރުގެންފި މީހަކަށެވެ. ތިޔަބައިމީހުން ކެތްތެރިވުން، ތިޔަބައިމީހުންނަށް ހެޔޮކަންބޮޑެވެ. ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₄ سورة النساء","26","يُرِيدُ ٱللَّهُ لِيُبَيِّنَ لَكُمۡ وَيَهۡدِيَكُمۡ سُنَنَ ٱلَّذِينَ مِن قَبۡلِكُمۡ وَيَتُوبَ عَلَيۡكُمۡۗ وَٱللَّهُ عَلِيمٌ حَكِيمٞ ٢٦","يريد الله ليبين لكم ويهديكم سنن الذين من قبلكم ويتوب عليكم والله عليم حكيم","ﷲ އިރާދަކުރައްވަނީ، ތިޔަބައިމީހުންނަށް (މަސްލަތު ހުރިގޮތް) ބަޔާން ކޮށްދެއްވުމަށެވެ. އަދި، ތިޔަބައިމީހުންގެ ކުރިން އުޅުނު (ރަނގަޅު) މީހުންގެ މަގުތަކަށް ތިޔަބައިމީހުންނަށް މަގުދެއްކެވުމަށެވެ. އަދި، ތިޔަބައިމީހުންގެ މައްޗަށް ތައުބާ ލެއްވުމަށެވެ. ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₄ سورة النساء","27","وَٱللَّهُ يُرِيدُ أَن يَتُوبَ عَلَيۡكُمۡ وَيُرِيدُ ٱلَّذِينَ يَتَّبِعُونَ ٱلشَّهَوَٰتِ أَن تَمِيلُواْ مَيۡلًا عَظِيمٗا ٢٧","والله يريد أن يتوب عليكم ويريد الذين يتبعون الشهوات أن تميلوا ميلا عظيما","އަދި، ﷲ އިރާދަކުރައްވަނީ، ތިޔަބައިމީހުންގެ މައްޗަށް ތައުބާ ލެއްވުމަށެވެ. އަދި، އަމިއްލަ އެދުންތަކަށް ތަބާވާ މީހުން އެދެނީ (ހައްގުގެ މަގު ފިޔަވައި ބާތިލުގެ މަގަށް) ބޮޑުވެގެންވާ ލެނބުމަކުން ތިޔަބައިމީހުން ލެނބިގަތުމަށެވެ.","",""],["₄ سورة النساء","28","يُرِيدُ ٱللَّهُ أَن يُخَفِّفَ عَنكُمۡۚ وَخُلِقَ ٱلۡإِنسَٰنُ ضَعِيفٗا ٢٨","يريد الله أن يخفف عنكم وخلق الإنسان ضعيفا","ﷲ އިރާދަކުރައްވަނީ، ތިޔަބައިމީހުންނަށް ލުއިކޮށް ދެއްވުމަށެވެ. އަދި، އިންސާނާ ހައްދަވާފައިވަނީ، (އެދުންތަކުގެ ކުރިމަތީގައި) ނިކަމެތިވެގެންވާ މީހެއް ކަމުގައެވެ.","",""],["₄ سورة النساء","29","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تَأۡكُلُوٓاْ أَمۡوَٰلَكُم بَيۡنَكُم بِٱلۡبَٰطِلِ إِلَّآ أَن تَكُونَ تِجَٰرَةً عَن تَرَاضٖ مِّنكُمۡۚ وَلَا تَقۡتُلُوٓاْ أَنفُسَكُمۡۚ إِنَّ ٱللَّهَ كَانَ بِكُمۡ رَحِيمٗا ٢٩","يا أيها الذين آمنوا لا تأكلوا أموالكم بينكم بالباطل إلا أن تكون تجارة عن تراض منكم ولا تقتلوا أنفسكم إن الله كان بكم رحيما","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ބާތިލު ގޮތުގައި ތިޔަބައިމީހުންގެ މުދާތައް ތިޔަބައިމީހުންގެ މެދުގައި ނުކާށެވެ! އެހެނެއްކަމަކު، ތިޔަބައިމީހުންގެ ތެރެއިން ދެފަރާތުގެ ރުހުމުގެ މައްޗަށް އޮންނަ ވިޔަފާރިޔަކަށްވުން މެނުވީއެވެ. އަދި، ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތައް ތިޔަބައިމީހުން ގަތުލު ނުކުރާށެވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ މައްޗަށް ރަޙީމްވަންތަ ރަސްކަލާނގެ ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","30","وَمَن يَفۡعَلۡ ذَٰلِكَ عُدۡوَٰنٗا وَظُلۡمٗا فَسَوۡفَ نُصۡلِيهِ نَارٗاۚ وَكَانَ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرًا ٣٠","ومن يفعل ذلك عدوانا وظلما فسوف نصليه نارا وكان ذلك على الله يسيرا","ދެކޮޅުވެރިކަމާއި، އަނިޔާވެރިކަމުގެ ގޮތުން އެކަންތައް ކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، ތިމަންރަސްކަލާނގެ އެމީހަކު ނަރަކަޔަށް ވައްދަވާހުށީމެވެ. އަދި، އެކަންތައް އެއީ، ﷲއަށް ދާދި ފަސޭހަކަމެއް ކަމުގައިވެއެވެ.","",""],["₄ سورة النساء","31","إِن تَجۡتَنِبُواْ كَبَآئِرَ مَا تُنۡهَوۡنَ عَنۡهُ نُكَفِّرۡ عَنكُمۡ سَيِّـَٔاتِكُمۡ وَنُدۡخِلۡكُم مُّدۡخَلٗا كَرِيمٗا ٣١","إن تجتنبوا كبائر ما تنهون عنه نكفر عنكم سيئاتكم وندخلكم مدخلا كريما","ތިޔަބައިމީހުންނަށް އެކަންކަން ނަހީކުރައްވާފައިވާ ބޮޑެތި ފާފަތަކުން ތިޔަބައިމީހުން ދުރުހެލިވެ ތިބޭނަމަ، ތިޔަބައިމީހުންގެ ކުދިކުދި ފާފަތައް ތިޔަބައިމީހުންގެ ކިބައިން، ތިމަންރަސްކަލާނގެ ފުއްސަވާ ހުށީމެވެ. އަދި، މާތްވެގެންވާ ތަނަކަށް، (އެބަހީ: ސުވަރުގެޔަށް) ތިމަންރަސްކަލާނގެ، ތިޔަބައިމީހުން ވައްދަވާހުށީމެވެ.","",""],["₄ سورة النساء","32","وَلَا تَتَمَنَّوۡاْ مَا فَضَّلَ ٱللَّهُ بِهِۦ بَعۡضَكُمۡ عَلَىٰ بَعۡضٖۚ لِّلرِّجَالِ نَصِيبٞ مِّمَّا ٱكۡتَسَبُواْۖ وَلِلنِّسَآءِ نَصِيبٞ مِّمَّا ٱكۡتَسَبۡنَۚ وَسۡـَٔلُواْ ٱللَّهَ مِن فَضۡلِهِۦٓۚ إِنَّ ٱللَّهَ كَانَ بِكُلِّ شَيۡءٍ عَلِيمٗا ٣٢","ولا تتمنوا ما فضل الله به بعضكم على بعض للرجال نصيب مما اكتسبوا وللنساء نصيب مما اكتسبن واسألوا الله من فضله إن الله كان بكل شيء عليما","ތިޔަބައިމީހުންގެ ތެރެއިން އެއްބަޔެއްގެ މައްޗަށް އަނެއްބަޔަކު މާތްކުރައްވައި، މޮޅުކުރެއްވި ކަންތަކަށް ތިޔަބައިމީހުން ނޭދޭށެވެ! ފިރިހެނުންނަށްވެސް، އެއުރެން ހޯދި ކަމެއްގެ ޖަޒާ ވެއެވެ. އަދި، އަންހެނުންނަށްވެސް، އެކަނބަލުން ހޯދި ކަމެއްގެ ޖަޒާ ވެއެވެ. އަދި، ﷲގެ ފަޟްލު ވަންތަކަމުގެ ތެރެއިން، (ދެއްވުމަށް) ތިޔަބައިމީހުން އެދޭށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެކަމެއްމެ މޮޅަށް ދެނެވޮޑިގެންވާ ކަލާނގެ ކަމުގައިވެއެވެ.","",""],["₄ سورة النساء","33","وَلِكُلّٖ جَعَلۡنَا مَوَٰلِيَ مِمَّا تَرَكَ ٱلۡوَٰلِدَانِ وَٱلۡأَقۡرَبُونَۚ وَٱلَّذِينَ عَقَدَتۡ أَيۡمَٰنُكُمۡ فَـَٔاتُوهُمۡ نَصِيبَهُمۡۚ إِنَّ ٱللَّهَ كَانَ عَلَىٰ كُلِّ شَيۡءٖ شَهِيدًا ٣٣","ولكل جعلنا موالي مما ترك الوالدان والأقربون والذين عقدت أيمانكم فآتوهم نصيبهم إن الله كان على كل شيء شهيدا","މައިންބަފައިންނާއި، ގާތްތިމާގެ މީހުން ދޫކޮށްފައިވާ މުދަލުން ވާރުތަވެގެން ލިބޭނެ ބަޔަކު، ކޮންމެ މީހަކަށްމެ ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ. އަދި، މުދަލުން ވާރުތަވުމަށް ތިޔަބައިމީހުން އަހުދުވެ، އެއްބަސްވެފައިވާ މީހުންނަށް އެއުރެންގެ ބައި، ތިޔަބައިމީހުން ދޭށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެ ކަމެއްގެ މައްޗަށް ހެކިވެ ވޮޑިގެންވާ ރަސްކަލާނގެ ކަމުގައިވެއެވެ.","",""],["₄ سورة النساء","34","ٱلرِّجَالُ قَوَّـٰ‌مُونَ عَلَى ٱلنِّسَآءِ بِمَا فَضَّلَ ٱللَّهُ بَعۡضَهُمۡ عَلَىٰ بَعۡضٖ وَبِمَآ أَنفَقُواْ مِنۡ أَمۡوَٰلِهِمۡۚ فَٱلصَّـٰلِحَٰتُ قَٰنِتَٰتٌ حَٰفِظَٰتٞ لِّلۡغَيۡبِ بِمَا حَفِظَ ٱللَّهُۚ وَٱلَّـٰتِي تَخَافُونَ نُشُوزَهُنَّ فَعِظُوهُنَّ وَٱهۡجُرُوهُنَّ فِي ٱلۡمَضَاجِعِ وَٱضۡرِبُوهُنَّۖ فَإِنۡ أَطَعۡنَكُمۡ فَلَا تَبۡغُواْ عَلَيۡهِنَّ سَبِيلًاۗ إِنَّ ٱللَّهَ كَانَ عَلِيّٗا كَبِيرٗا ٣٤","الرجال قوامون على النساء بما فضل الله بعضهم على بعض وبما أنفقوا من أموالهم فالصالحات قانتات حافظات للغيب بما حفظ الله واللاتي تخافون نشوزهن فعظوهن واهجروهن في المضاجع واضربوهن فإن أطعنكم فلا تبغوا عليهن سبيلا إن الله كان عليا كبيرا","ފިރިހެނުންނަކީ، އަންހެނުންގެ މައްޗަށް ރައްކާތެރިވެ ބެލެހެއްޓުމުގައި ގާއިމު ވެގެންތިބޭ ބަޔެކެވެ. (އެއީ) އެއުރެންގެ އެއްބަޔެއްގެ މައްޗަށް އަނެއްބަޔަކު ﷲ މާތްކުރައްވައި، އިތުރުކުރައްވާފައިވާ ކަމަށްޓަކައެވެ. އަދި، އެއުރެންގެ މުދަލުން ހޭދަކޮށްފައިވާ ކަމަށްޓަކައެވެ. ފަހެ، ހެޔޮލަފާ އަންހެނުންނަކީ، ކިޔަމަންތެރި އަންހެނުންނެވެ. ރައްކާތެރިކުރުމަށް ﷲ އެންގެވި ކަންތައް، ސިއްރުގައިވެސް، ރައްކާތެރިކުރާ އަންހެނުންނެވެ. އެކަނބަލުން ނުކިޔަމަންތެރިވެދާނެކަމަށް، ތިޔަބައިމީހުން ބިރުގަންނަނަމަ، ފަހެ، އެކަނބަލުންނަށް ނަސޭހަތް ދޭށެވެ! އަދި، އެކަނބަލުންނާއެކު އެއްދާންކުރުން ދޫކޮށްލާށެވެ! އަދި، އެކަނބަލުންގެ ގައިގައި (ހާނީއްކަ ނުވާގޮތުން) ޖަހާށެވެ! ފަހެ، ތިޔަބައިމީހުންނަށް އެކަނބަލުން ކިޔަމަންވެއްޖެނަމަ، އެކަނބަލުންގެ މައްޗަށް (އަނިޔާވެރި) މަގަކަށް ނޭދޭށެވެ! ހަމަކަށަވަރުން، ﷲއީ، އެންމެ މަތިވެރި، އެންމެ ބޮޑު ރަސްކަލާނގެ ކަމުގައިވެއެވެ.","",""],["₄ سورة النساء","35","وَإِنۡ خِفۡتُمۡ شِقَاقَ بَيۡنِهِمَا فَٱبۡعَثُواْ حَكَمٗا مِّنۡ أَهۡلِهِۦ وَحَكَمٗا مِّنۡ أَهۡلِهَآ إِن يُرِيدَآ إِصۡلَٰحٗا يُوَفِّقِ ٱللَّهُ بَيۡنَهُمَآۗ إِنَّ ٱللَّهَ كَانَ عَلِيمًا خَبِيرٗا ٣٥","وإن خفتم شقاق بينهما فابعثوا حكما من أهله وحكما من أهلها إن يريدا إصلاحا يوفق الله بينهما إن الله كان عليما خبيرا","އެދެމީހުންގެ ދެމެދުގައި ދެކޮޅުވެރިކަމެއް އުފެދި، އެކަމާމެދު ތިޔަބައިމީހުން ބިރުގެންފިނަމަ، އޭނާގެ އަހުލުވެރިންގެ ތެރެއިން ނިޔާވެރިޔަކާއި، އެކަނބުލޭގެ އަހުލުވެރިންގެ ތެރެއިން ނިޔާވެރިޔަކު ތިޔަބައިމީހުން ފޮނުވާށެވެ! ސުލްހަކުރުމަށް އެދެމީހުން ގަސްދުކުރާނަމަ، ﷲ، އެ ދެމީހުން ސުލްހަކުރައްވައި، އެއްބަސް ކުރައްވައިފާނެތެވެ. ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ ޚައިބަރުވަންތަ ރަސްކަލާނގެ ކަމުގައިވެއެވެ.","",""],["₄ سورة النساء","36","۞وَٱعۡبُدُواْ ٱللَّهَ وَلَا تُشۡرِكُواْ بِهِۦ شَيۡـٔٗاۖ وَبِٱلۡوَٰلِدَيۡنِ إِحۡسَٰنٗا وَبِذِي ٱلۡقُرۡبَىٰ وَٱلۡيَتَٰمَىٰ وَٱلۡمَسَٰكِينِ وَٱلۡجَارِ ذِي ٱلۡقُرۡبَىٰ وَٱلۡجَارِ ٱلۡجُنُبِ وَٱلصَّاحِبِ بِٱلۡجَنۢبِ وَٱبۡنِ ٱلسَّبِيلِ وَمَا مَلَكَتۡ أَيۡمَٰنُكُمۡۗ إِنَّ ٱللَّهَ لَا يُحِبُّ مَن كَانَ مُخۡتَالٗا فَخُورًا ٣٦","واعبدوا الله ولا تشركوا به شيئا وبالوالدين إحسانا وبذي القربى واليتامى والمساكين والجار ذي القربى والجار الجنب والصاحب بالجنب وابن السبيل وما ملكت أيمانكم إن الله لا يحب من كان مختالا فخورا","ތިޔަބައިމީހުން، ﷲއަށް އަޅުކަންކުރާށެވެ! އަދި، އެކަލާނގެއަށް އެއްވެސް އެއްޗެއް ޝަރީކު ނުކުރާހުށިކަމެވެ! އަދި، މައިންބަފައިންނަށާއި، ގާތްތިމާގެ މީހުންނަށާއި، ޔަތީމުންނަށާއި، މިސްކީނުންނަށާއި، ގާތް އަވަށްޓެރިޔާއަށާއި، ދުރު އަވަށްޓެރިޔާއަށާއި، ކައިރި އެކުވެރިޔާއަށާއި، ދަތުރުވެރިޔާއަށާއި، ތިޔަބައިމީހުންނަށް މިލްކުވެގެންވާ އަޅުންނަށް ހެޔޮކޮށް ހިތާށެވެ! ހަމަކަށަވަރުން، ތިމާގެ މޮޅުކަން ތިމާޔަށްފެނި، ބޮޑާވެގެން އުޅޭ މީހަކުކަމުގައި ވެއްޖެ މީހަކުދެކެ، ﷲ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["₄ سورة النساء","37","ٱلَّذِينَ يَبۡخَلُونَ وَيَأۡمُرُونَ ٱلنَّاسَ بِٱلۡبُخۡلِ وَيَكۡتُمُونَ مَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضۡلِهِۦۗ وَأَعۡتَدۡنَا لِلۡكَٰفِرِينَ عَذَابٗا مُّهِينٗا ٣٧","الذين يبخلون ويأمرون الناس بالبخل ويكتمون ما آتاهم الله من فضله وأعتدنا للكافرين عذابا مهينا","އެއުރެންނީ، ދަހިވެތިވާ މީހުންނެވެ. އަދި، ދަހިވެތިވުމަށް މީސްތަކުންނަށް އަމުރުކުރާ މީހުންނެވެ. އަދި، ﷲ، އެކަލާނގެ ފަޟްލު ވަންތަކަމުގެ ތެރެއިން އެބަޔަކަށް ދެއްވާފައިވާ ތަކެއްޗާއި ކަންތައް ވަންހަނާކުރާ މީހުންނެވެ. ކާފިރުންނަށްޓަކައި، އިހާނަތްތެރި އަޒާބު ތިމަންރަސްކަލާނގެ ތައްޔާރު ކުރެއްވީމެވެ.","",""],["₄ سورة النساء","38","وَٱلَّذِينَ يُنفِقُونَ أَمۡوَٰلَهُمۡ رِئَآءَ ٱلنَّاسِ وَلَا يُؤۡمِنُونَ بِٱللَّهِ وَلَا بِٱلۡيَوۡمِ ٱلۡأٓخِرِۗ وَمَن يَكُنِ ٱلشَّيۡطَٰنُ لَهُۥ قَرِينٗا فَسَآءَ قَرِينٗا ٣٨","والذين ينفقون أموالهم رئاء الناس ولا يؤمنون بالله ولا باليوم الآخر ومن يكن الشيطان له قرينا فساء قرينا","އަދި، އެއުރެންނަކީ، މީސްތަކުންނަށް ދެއްކުމަށްޓަކައި އެއުރެންގެ މުދާތައް ހޭދަކޮށް އުޅޭމީހުންނެވެ. އަދި، ﷲއަށާއި، އާޚިރަތް ދުވަހަށް އީމާން ނުވާ މީހުންނެވެ. ޝައިތާނާ، އެމީހެއްގެ އެކުވެރިޔަކު ކަމުގައިވާ މީހާ، (ދަންނާށެވެ!) ފަހެ، އެކަލޭގެއީ، ހާދަހާ ނުބައިވެގެންވާ އެކުވެރިއެކެވެ.","",""],["₄ سورة النساء","39","وَمَاذَا عَلَيۡهِمۡ لَوۡ ءَامَنُواْ بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِ وَأَنفَقُواْ مِمَّا رَزَقَهُمُ ٱللَّهُۚ وَكَانَ ٱللَّهُ بِهِمۡ عَلِيمًا ٣٩","وماذا عليهم لو آمنوا بالله واليوم الآخر وأنفقوا مما رزقهم الله وكان الله بهم عليما","އެއުރެން ﷲއަށާއި، އާޚިރަތް ދުވަހަށް އީމާންވެ، އެއުރެންނަށް ﷲ ދެއްވި ތަކެތިން އެއުރެން ހޭދަކޮށްއުޅުނުނަމަ، އެއުރެންގެ މައްޗަށް އޮތީ ކޮންކަމެއްހެއްޔެވެ؟ އެއުރެންގެ ކަންތައް، މޮޅަށް ދެނެވޮޑިގެންވާ ކަލާނގެ ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","40","إِنَّ ٱللَّهَ لَا يَظۡلِمُ مِثۡقَالَ ذَرَّةٖۖ وَإِن تَكُ حَسَنَةٗ يُضَٰعِفۡهَا وَيُؤۡتِ مِن لَّدُنۡهُ أَجۡرًا عَظِيمٗا ٤٠","إن الله لا يظلم مثقال ذرة وإن تك حسنة يضاعفها ويؤت من لدنه أجرا عظيما","ﷲ، (އެއްވެސް މީހަކަށް) ޒައްރެއްގެ މިންވަރުވިޔަސް ބޭއިންސާފެއް ނުކުރައްވާނެކަން ކަށަވަރެވެ. އެއީ، ހެޔޮކަމެއް ކަމުގައިވާނަމަ، އެކަންތައް (އެބަހީ: އޭގެ ސަވާބު) ގިނަގުނަ ކުރައްވަތެވެ. އަދި، އެކަލާނގެ ހަޒުރަތުން ބޮޑުވެގެންވާ ދަރުމަ ދެއްވަތެވެ.","",""],["₄ سورة النساء","41","فَكَيۡفَ إِذَا جِئۡنَا مِن كُلِّ أُمَّةِۭ بِشَهِيدٖ وَجِئۡنَا بِكَ عَلَىٰ هَـٰٓؤُلَآءِ شَهِيدٗا ٤١","فكيف إذا جئنا من كل أمة بشهيد وجئنا بك على هؤلاء شهيدا","ފަހެ، ތިމަންރަސްކަލާނގެ ކޮންމެ އުއްމަތަކުން ހެކިވެރިޔަކު، (އެބަހީ: އެއުރެންގެ މައްޗަށް ހެކިވުމަށްޓަކައި އެ އުއްމަތެއްގެ ނަބިއްޔަކު) ގެންނަވައި، އަދި، މިބައިމީހުންގެ މައްޗަށް ހެކިވެރިޔެއްގެ ގޮތުގައި ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ގެންނަވާހިނދު، (ކާފިރުންގެ ޙާލު) ކޮންފަދަތޯއެވެ؟","",""],["₄ سورة النساء","42","يَوۡمَئِذٖ يَوَدُّ ٱلَّذِينَ كَفَرُواْ وَعَصَوُاْ ٱلرَّسُولَ لَوۡ تُسَوَّىٰ بِهِمُ ٱلۡأَرۡضُ وَلَا يَكۡتُمُونَ ٱللَّهَ حَدِيثٗا ٤٢","يومئذ يود الذين كفروا وعصوا الرسول لو تسوى بهم الأرض ولا يكتمون الله حديثا","ކާފިރުވެ، ރަސޫލާއަށް ނުކިޔަމަންތެރިވި މީހުން އެއުރެން ބިމާ ހަމަހަމަވެގެން ދާނެނަމައޭ ހީކޮށް، އެގޮތްވުމަށް އެދުވަހު އެދޭނެތެވެ. އަދި، (އެދުވަހުން) އެއުރެންނަކަށް ﷲއަށް އެއްވެސް ކަމެއް ވަންހަނާއެއް ނުކުރެވޭނެތެވެ.","",""],["₄ سورة النساء","43","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تَقۡرَبُواْ ٱلصَّلَوٰةَ وَأَنتُمۡ سُكَٰرَىٰ حَتَّىٰ تَعۡلَمُواْ مَا تَقُولُونَ وَلَا جُنُبًا إِلَّا عَابِرِي سَبِيلٍ حَتَّىٰ تَغۡتَسِلُواْۚ وَإِن كُنتُم مَّرۡضَىٰٓ أَوۡ عَلَىٰ سَفَرٍ أَوۡ جَآءَ أَحَدٞ مِّنكُم مِّنَ ٱلۡغَآئِطِ أَوۡ لَٰمَسۡتُمُ ٱلنِّسَآءَ فَلَمۡ تَجِدُواْ مَآءٗ فَتَيَمَّمُواْ صَعِيدٗا طَيِّبٗا فَٱمۡسَحُواْ بِوُجُوهِكُمۡ وَأَيۡدِيكُمۡۗ إِنَّ ٱللَّهَ كَانَ عَفُوًّا غَفُورًا ٤٣","يا أيها الذين آمنوا لا تقربوا الصلاة وأنتم سكارى حتى تعلموا ما تقولون ولا جنبا إلا عابري سبيل حتى تغتسلوا وإن كنتم مرضى أو على سفر أو جاء أحد منكم من الغائط أو لامستم النساء فلم تجدوا ماء فتيمموا صعيدا طيبا فامسحوا بوجوهكم وأيديكم إن الله كان عفوا غفورا","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން (ނަމާދުގައި) ކިޔާ އެއްޗެއް ތިޔަބައިމީހުންނަށް އެނގިއްޖައުމަށް ދާނދެން، ތިޔަބައިމީހުން މަސްތުވެގެން ތިބޭ ޙާލު ތިޔަބައިމީހުން ނަމާދާ ގާތްނުވާށެވެ! އަދި، މަގު ހުރަސްކޮށް ދަތުރުކުރާ ދަތުރުވެރިން މެނުވީ، ޖުނުބުވެރިވެގެންވާ ޙާލު ވެސް، ތިޔަބައިމީހުން ހިނައިގެންފުމަށް ދާނދެން، (ނަމާދާ ގާތްނުވާށެވެ!) އަދި، ބަލިމީހުން ކަމުގައި ތިޔަބައިމީހުން ވާނަމަ، ނުވަތަ، ދަތުރެއްގެ މަތީގައިވާނަމަ، ނުވަތަ، ތިޔަބައިމީހުންކުރެ މީހަކު ހަނޑަހުން އައިނަމަ، (އެބަހީ: ކުޑަކަމު ނުވަތަ ބޮޑުކަމު ހިނގައްޖެނަމަ) ނުވަތަ، އަންހެނުންގައި ތިޔަބައިމީހުން ބީހިއްޖެނަމަ، ދެން، ތިޔަބައިމީހުންނަށް ފެން ނުލިބިއްޖިއްޔާ، ތާހިރު ވެލިން ތިޔަބައިމީހުން ތަޔައްމަމުކުރާށެވެ! ފަހެ، ތިޔަބައިމީހުންގެ މޫނުތަކާއި، އަތްތަކުގައި، (އެ ވެލިން) ފުހޭށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން އަފޫކުރައްވާ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަސްކަލާނގެ ކަމުގައިވެއެވެ.","",""],["₄ سورة النساء","44","أَلَمۡ تَرَ إِلَى ٱلَّذِينَ أُوتُواْ نَصِيبٗا مِّنَ ٱلۡكِتَٰبِ يَشۡتَرُونَ ٱلضَّلَٰلَةَ وَيُرِيدُونَ أَن تَضِلُّواْ ٱلسَّبِيلَ ٤٤","ألم تر إلى الذين أوتوا نصيبا من الكتاب يشترون الضلالة ويريدون أن تضلوا السبيل","ފޮތުގެ ތެރެއިން ބައެއް އެއުރެންނަށް ލިބުނު މީހުން، ކަލޭގެފާނު ދެކެވަޑައެއް ނުގަންނަވަމުތޯއެވެ؟ އެއުރެން މަގުފުރެދުން ގަނެތެވެ. އަދި، ތިޔަބައިމީހުން މަގުފުރެދުމަށްވެސް އެއުރެން އެދެތެވެ.","",""],["₄ سورة النساء","45","وَٱللَّهُ أَعۡلَمُ بِأَعۡدَآئِكُمۡۚ وَكَفَىٰ بِٱللَّهِ وَلِيّٗا وَكَفَىٰ بِٱللَّهِ نَصِيرٗا ٤٥","والله أعلم بأعدائكم وكفى بالله وليا وكفى بالله نصيرا","ﷲ ތިޔަބައިމީހުންގެ އަދާވަތް ތެރިން ދެނެވޮޑިގަތުން ބޮޑެވެ. އަދި، އެހީތެރިޔަކުކަމުގައި ﷲ ފުދެއެވެ. އަދި، ނަސްރުވެރިޔަކު ކަމުގައިވެސް ﷲ ފުދެއެވެ.","",""],["₄ سورة النساء","46","مِّنَ ٱلَّذِينَ هَادُواْ يُحَرِّفُونَ ٱلۡكَلِمَ عَن مَّوَاضِعِهِۦ وَيَقُولُونَ سَمِعۡنَا وَعَصَيۡنَا وَٱسۡمَعۡ غَيۡرَ مُسۡمَعٖ وَرَٰعِنَا لَيَّۢا بِأَلۡسِنَتِهِمۡ وَطَعۡنٗا فِي ٱلدِّينِۚ وَلَوۡ أَنَّهُمۡ قَالُواْ سَمِعۡنَا وَأَطَعۡنَا وَٱسۡمَعۡ وَٱنظُرۡنَا لَكَانَ خَيۡرٗا لَّهُمۡ وَأَقۡوَمَ وَلَٰكِن لَّعَنَهُمُ ٱللَّهُ بِكُفۡرِهِمۡ فَلَا يُؤۡمِنُونَ إِلَّا قَلِيلٗا ٤٦","من الذين هادوا يحرفون الكلم عن مواضعه ويقولون سمعنا وعصينا واسمع غير مسمع وراعنا ليا بألسنتهم وطعنا في الدين ولو أنهم قالوا سمعنا وأطعنا واسمع وانظرنا لكان خيرا لهم وأقوم ولكن لعنهم الله بكفرهم فلا يؤمنون إلا قليلا","ބަސްތައް ހުންނަންވީ ތަންތަނުން ބަދަލުކޮށް، އޮޅުވާމީހުން ޔަހޫދީންގެ ތެރެއިންވެއެވެ. އަދި، ތިމަންމެން އަހައިފީމުއޭ، އަދި، ތިމަންމެން އުރެދިއްޖައީމުއޭ، އަދި، ނީވޭމީހެއްގެ ގޮތުގައި އައްސަވާށޭ، އަދި، ތިމަންމެންނަށް ބައްލަވާށޭ، އެއުރެން ބުނެތެވެ. (އެއުރެން އެފަދަ ބަސްތައް ބުނަނީ) އެއުރެންގެ ދޫތަކުން ބަސްތައް އޮޅުވާލުމުގެ ގޮތުންނެވެ. އަދި، ދީނާ މެދުގައި ނިކަމެތި ބަސްބުނުމުގެ ގޮތުންނެވެ. ތިމަންމެން އަހައިފީމުއޭ، އަދި، ކިޔަމަން ވެއްޖައީމުއޭ، އަދި، އައްސަވާށޭ، އަދި، ތިމަންމެންނަށްޓަކައި ލަސްކޮށްލައްވާ އިންތިޒާރުކުރައްވާށޭ (މިހެން) އެއުރެން ބުނިނަމަ، އެއުރެންނަށް ހެޔޮކަން މާބޮޑުވީހެވެ. އަދި، ސީދާކަންވެސް މާބޮޑުވީހެވެ. އެހެނެއްކަމަކު، އެއުރެން ކާފިރު ވުމުގެ ސަބަބުން ﷲ، އެއުރެންނަށް ލައުނަތް ލެއްވިއެވެ. ފަހެ، (އޭގެތެރެއިން) މަދުބަޔަކުމެނުވީ އީމާނެއް ނުވެތެވެ.","",""],["₄ سورة النساء","47","يَـٰٓأَيُّهَا ٱلَّذِينَ أُوتُواْ ٱلۡكِتَٰبَ ءَامِنُواْ بِمَا نَزَّلۡنَا مُصَدِّقٗا لِّمَا مَعَكُم مِّن قَبۡلِ أَن نَّطۡمِسَ وُجُوهٗا فَنَرُدَّهَا عَلَىٰٓ أَدۡبَارِهَآ أَوۡ نَلۡعَنَهُمۡ كَمَا لَعَنَّآ أَصۡحَٰبَ ٱلسَّبۡتِۚ وَكَانَ أَمۡرُ ٱللَّهِ مَفۡعُولًا ٤٧","يا أيها الذين أوتوا الكتاب آمنوا بما نزلنا مصدقا لما معكم من قبل أن نطمس وجوها فنردها على أدبارها أو نلعنهم كما لعنا أصحاب السبت وكان أمر الله مفعولا","އޭ ފޮތް ލިބުނު މީހުންނޭވެ! ތިޔަބައިމީހުންނާ އެކުގައިވާ ފޮތް ތެދުކުރާގޮތުގައި، ތިމަންރަސްކަލާނގެ ބާވައިލެއްވި ފޮތަށް (އެބަހީ: ގުރްއާނަށް) ތިޔަބައިމީހުން އީމާން ވާށެވެ! (އެއީ) މޫނުތަކެއް ބަދަލުކުރައްވައި، ތިމަންރަސްކަލާނގެ އެ މޫނުތައް ފުރަގަހަށް ރައްދުކުރެއްވުމުގެ ކުރިންނެވެ. (އެބަހީ: އެއުރެންގެ މައްޗަށް އަޒާބެއް ފޮނުއްވުމުގެ ކުރިންނެވެ.) ނުވަތަ، ހޮނިހިރުގެ އަހުލުވެރިންނަށް، ތިމަންރަސްކަލާނގެ ލައުނަތް ލެއްވިފަދައިން، އެއުރެންނަށް ލައުނަތް ލެއްވުމުގެ ކުރިންނެވެ. ﷲގެ އަމުރުފުޅު އެއީ، ހިނގަނިވިކަމެއް ކަމުގައިވެއެވެ.","",""],["₄ سورة النساء","48","إِنَّ ٱللَّهَ لَا يَغۡفِرُ أَن يُشۡرَكَ بِهِۦ وَيَغۡفِرُ مَا دُونَ ذَٰلِكَ لِمَن يَشَآءُۚ وَمَن يُشۡرِكۡ بِٱللَّهِ فَقَدِ ٱفۡتَرَىٰٓ إِثۡمًا عَظِيمًا ٤٨","إن الله لا يغفر أن يشرك به ويغفر ما دون ذلك لمن يشاء ومن يشرك بالله فقد افترى إثما عظيما","ހަމަކަށަވަރުން، ﷲ، އެކަލާނގެއަށް ޝަރީކުކުރުމުގެ ފާފައެއް ނުފުއްސަވާނެތެވެ. އެނޫން ފާފަތައް، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ފުއްސަވަތެވެ. އަދި، ﷲއަށް ޝަރީކުކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާ ބޮޑުވެގެންވާ ފާފައަކަށް އަރައިގެންފިކަން ކަށަވަރެވެ.","",""],["₄ سورة النساء","49","أَلَمۡ تَرَ إِلَى ٱلَّذِينَ يُزَكُّونَ أَنفُسَهُمۚ بَلِ ٱللَّهُ يُزَكِّي مَن يَشَآءُ وَلَا يُظۡلَمُونَ فَتِيلًا ٤٩","ألم تر إلى الذين يزكون أنفسهم بل الله يزكي من يشاء ولا يظلمون فتيلا","ތިމާމެންގެ އަމިއްލަ ނަފްސުތަކަށް ތާރީފުކުރާ މީހުން، ކަލޭގެފާނު ދެކެވަޑައި ނުގަންނަވަމުތޯއެވެ؟ އަދި ކިއެއްތަ! ﷲ، އެކަލާނގެ އިރާދަކުރެއްވި މީހަކަށް ތާރީފުކުރައްވަތެވެ. އަދި، ކިތަންމެކުޑަ މިންވަރަކުން ވިޔަސް، އެއުރެންނަށް ބޭއިންސާފެއް ނުކުރައްވާނެއެވެ.","",""],["₄ سورة النساء","50","ٱنظُرۡ كَيۡفَ يَفۡتَرُونَ عَلَى ٱللَّهِ ٱلۡكَذِبَۖ وَكَفَىٰ بِهِۦٓ إِثۡمٗا مُّبِينًا ٥٠","انظر كيف يفترون على الله الكذب وكفى به إثما مبينا","ﷲއާމެދު، އެއުރެން ދޮގު ހަދާގޮތް ކަލޭގެފާނު ދެކެވަޑައިގެން ބައްލަވާށެވެ! ބަޔާން ވެގެންވާ ފާފައެއްކަމުގައި އެކަންތައް ފުދެއެވެ.","",""],["₄ سورة النساء","51","أَلَمۡ تَرَ إِلَى ٱلَّذِينَ أُوتُواْ نَصِيبٗا مِّنَ ٱلۡكِتَٰبِ يُؤۡمِنُونَ بِٱلۡجِبۡتِ وَٱلطَّـٰغُوتِ وَيَقُولُونَ لِلَّذِينَ كَفَرُواْ هَـٰٓؤُلَآءِ أَهۡدَىٰ مِنَ ٱلَّذِينَ ءَامَنُواْ سَبِيلًا ٥١","ألم تر إلى الذين أوتوا نصيبا من الكتاب يؤمنون بالجبت والطاغوت ويقولون للذين كفروا هؤلاء أهدى من الذين آمنوا سبيلا","ފޮތުގެ ތެރެއިން ބައެއް އެއުރެންނަށް ލިބުނު މީހުން، ކަލޭގެފާނު ދެކެވަޑައެއް ނުގަންނަވަމުތޯއެވެ؟ އެއުރެން ބުދަށާއި، ޝައިތާނު އާޔަށް އީމާން ވެއެވެ. އަދި، ކާފިރުވި މީހުންނަށް، އެއުރެން ބުނެތެވެ. އީމާން ވެގެން ތިބި މީހުންނަށްވުރެން، މިބައިމީހުންނަށް ތެދުމަގު ލިބުން ބޮޑެވެ.","",""],["₄ سورة النساء","52","أُوْلَـٰٓئِكَ ٱلَّذِينَ لَعَنَهُمُ ٱللَّهُۖ وَمَن يَلۡعَنِ ٱللَّهُ فَلَن تَجِدَ لَهُۥ نَصِيرًا ٥٢","أولئك الذين لعنهم الله ومن يلعن الله فلن تجد له نصيرا","އެއުރެންނަކީ، ހަމަ ﷲ، ލައުނަތް ލައްވާފައިވާ މީހުންނެވެ. ﷲ، ލައުނަތް ލައްވާ މީހާ، (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް ނަސްރުވެރިވާނޭ މީހަކު ތިބާޔަކަށް ނުފެންނާނެތެވެ.","",""],["₄ سورة النساء","53","أَمۡ لَهُمۡ نَصِيبٞ مِّنَ ٱلۡمُلۡكِ فَإِذٗا لَّا يُؤۡتُونَ ٱلنَّاسَ نَقِيرًا ٥٣","أم لهم نصيب من الملك فإذا لا يؤتون الناس نقيرا","ނުވަތަ، ވެރިކަމުގެ ތެރެއިން ބައެއް އެއުރެންނަށް ލިބިގެންވަނީހެއްޔެވެ؟ ފަހެ، އެހެންވެއްޖިއްޔާ އެއުރެން މީސްތަކުންނަށް ކިތަންމެ ކުޑަމިންވަރެއްވިޔަސް ނުދޭނެތެވެ.","",""],["₄ سورة النساء","54","أَمۡ يَحۡسُدُونَ ٱلنَّاسَ عَلَىٰ مَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضۡلِهِۦۖ فَقَدۡ ءَاتَيۡنَآ ءَالَ إِبۡرَٰهِيمَ ٱلۡكِتَٰبَ وَٱلۡحِكۡمَةَ وَءَاتَيۡنَٰهُم مُّلۡكًا عَظِيمٗا ٥٤","أم يحسدون الناس على ما آتاهم الله من فضله فقد آتينا آل إبراهيم الكتاب والحكمة وآتيناهم ملكا عظيما","ނުވަތަ، ﷲގެ ފަޟްލު ވަންތަކަމުގެ ތެރެއިން، އެކަލާނގެ މީސްތަކުންނަށް ދެއްވާފައިވާ ކަންތަކާމެދު އެއުރެން (އެބަހީ: ޔަހޫދީން) މީސްތަކުންނަށް ހަސަދަވެރި ވަނީހެއްޔެވެ؟ ފަހެ، ހަމަކަށަވަރުން، އިބްރާހީމްގެފާނުންގެ އާލުވެރިންނަށް، ފޮތާއި ހިކުމަތް، ތިމަންރަސްކަލާނގެ ދެއްވީމެވެ. އަދި، ބޮޑުވެގެންވާ ވެރިކަމެއް، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްވީމެވެ.","",""],["₄ سورة النساء","55","فَمِنۡهُم مَّنۡ ءَامَنَ بِهِۦ وَمِنۡهُم مَّن صَدَّ عَنۡهُۚ وَكَفَىٰ بِجَهَنَّمَ سَعِيرًا ٥٥","فمنهم من آمن به ومنهم من صد عنه وكفى بجهنم سعيرا","ފަހެ، އެކަލޭގެފާނަށް (އެބަހީ: މުޙައްމަދުގެފާނަށް) އީމާންވި މީހުން އެއުރެންގެ ތެރެއިންވެއެވެ. އަދި، އެކަލޭގެފާނަށް ފުރަގަސްދިން މީހުންވެސް އެއުރެންގެ ތެރެއިންވެއެވެ. (އެއުރެންނަށްޓަކައި) އަނދައަނދާ ހުންނަ އަލިފާންގަނޑެއް ކަމުގައި ޖަހައްނަމަ ފުދެއެވެ.","",""],["₄ سورة النساء","56","إِنَّ ٱلَّذِينَ كَفَرُواْ بِـَٔايَٰتِنَا سَوۡفَ نُصۡلِيهِمۡ نَارٗا كُلَّمَا نَضِجَتۡ جُلُودُهُم بَدَّلۡنَٰهُمۡ جُلُودًا غَيۡرَهَا لِيَذُوقُواْ ٱلۡعَذَابَۗ إِنَّ ٱللَّهَ كَانَ عَزِيزًا حَكِيمٗا ٥٦","إن الذين كفروا بآياتنا سوف نصليهم نارا كلما نضجت جلودهم بدلناهم جلودا غيرها ليذوقوا العذاب إن الله كان عزيزا حكيما","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް ކާފިރުވި މީހުން ނިކަންހުރެ ތިމަންރަސްކަލާނގެ އެއުރެން ނަރަކަޔަށް ވައްދަވާ ހުށީމެވެ. އެއުރެންގެ ހަންތައް ރޯފިލައްޖެ ކޮންމެހިނދަކު، އެއުރެންގެ ހަންތައް އެނޫން ހަންތަކަކަށް ބަދަލުކުރައްވަމެވެ. އެއީ، އެއުރެން އަޒާބުގެ ރަހަ ލިބިގަތުމަށްޓަކައެވެ. ހަމަކަށަވަރުން، ﷲއީ، ޢަޒީޒުވަންތަ ޙަކީމްވަންތަ ރަސްކަލާނގެ ކަމުގައިވެއެވެ.","",""],["₄ سورة النساء","57","وَٱلَّذِينَ ءَامَنُواْ وَعَمِلُواْ ٱلصَّـٰلِحَٰتِ سَنُدۡخِلُهُمۡ جَنَّـٰتٖ تَجۡرِي مِن تَحۡتِهَا ٱلۡأَنۡهَٰرُ خَٰلِدِينَ فِيهَآ أَبَدٗاۖ لَّهُمۡ فِيهَآ أَزۡوَٰجٞ مُّطَهَّرَةٞۖ وَنُدۡخِلُهُمۡ ظِلّٗا ظَلِيلًا ٥٧","والذين آمنوا وعملوا الصالحات سندخلهم جنات تجري من تحتها الأنهار خالدين فيها أبدا لهم فيها أزواج مطهرة وندخلهم ظلا ظليلا","އަދި، އީމާންވެ، ސާލިހު ޢަމަލުކުޅަމީހުން، އެތާނގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކަކަށް، ތިމަންރަސްކަލާނގެ އެއުރެން ވައްދަވާހުށީމެވެ. އެ ސުވަރުގެތަކުގައި، އެއުރެން، އަބަދަށް ދެމިތިބެނިވި ގޮތުގައެވެ. އެތާނގައި އެއުރެންނަށް ތާހިރުކުރައްވާފައިވާ އަނބިންތަކެއް ވެއެވެ. އަދި، ހިޔާދެނިވި ހިޔަލަކަށް، ތިމަންރަސްކަލާނގެ އެއުރެން ވައްދަވާހުށީމެވެ.","",""],["₄ سورة النساء","58","۞إِنَّ ٱللَّهَ يَأۡمُرُكُمۡ أَن تُؤَدُّواْ ٱلۡأَمَٰنَٰتِ إِلَىٰٓ أَهۡلِهَا وَإِذَا حَكَمۡتُم بَيۡنَ ٱلنَّاسِ أَن تَحۡكُمُواْ بِٱلۡعَدۡلِۚ إِنَّ ٱللَّهَ نِعِمَّا يَعِظُكُم بِهِۦٓۗ إِنَّ ٱللَّهَ كَانَ سَمِيعَۢا بَصِيرٗا ٥٨","إن الله يأمركم أن تؤدوا الأمانات إلى أهلها وإذا حكمتم بين الناس أن تحكموا بالعدل إن الله نعما يعظكم به إن الله كان سميعا بصيرا","ހަމަކަށަވަރުން، އަމާނަތްތައް، އޭގެ އަހުލުވެރިންނަށް އަދާކުރުމަށް، ﷲ ތިޔަބައިމީހުންނަށް އަމުރުކުރައްވަތެވެ. އަދި، މީސްތަކުންގެ މެދުގައި ތިޔަބައިމީހުން ހުކުމްކުރާނަމަ، ޢަދުލަށް ހުކުމްކުރުމަށްވެސް، އަމުރުކުރައްވަތެވެ. ހަމަކަށަވަރުން، ﷲ އެކަމަކާމެދު، ތިޔަބައިމީހުންނަށް ވައުޒު އިއްވަވާކަމެއްގެ މޮޅުކަމާއެވެ! ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ބައްލަވާވޮޑިގެންވާ ކަލަކު ކަމުގައިވެއެވެ.","",""],["₄ سورة النساء","59","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ أَطِيعُواْ ٱللَّهَ وَأَطِيعُواْ ٱلرَّسُولَ وَأُوْلِي ٱلۡأَمۡرِ مِنكُمۡۖ فَإِن تَنَٰزَعۡتُمۡ فِي شَيۡءٖ فَرُدُّوهُ إِلَى ٱللَّهِ وَٱلرَّسُولِ إِن كُنتُمۡ تُؤۡمِنُونَ بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِۚ ذَٰلِكَ خَيۡرٞ وَأَحۡسَنُ تَأۡوِيلًا ٥٩","يا أيها الذين آمنوا أطيعوا الله وأطيعوا الرسول وأولي الأمر منكم فإن تنازعتم في شيء فردوه إلى الله والرسول إن كنتم تؤمنون بالله واليوم الآخر ذلك خير وأحسن تأويلا","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން، ﷲއަށް ކިޔަމަންވާށެވެ! އަދި، ރަސޫލާއަށާއި، ތިޔަބައިމީހުންގެ ތެރެއިން ވެރިންނަށްވެސް ކިޔަމަންވާށެވެ! ފަހެ، ކަމަކާމެދު ތިޔަބައިމީހުން ދެބަސްވެއްޖެނަމަ، ﷲއަށާއި، ރަސޫލާއަށް އެކަމެއް ރައްދުކުރާށެވެ! (އެބަހީ: އެކަމާމެދު ﷲއާއި، އެކަލާނގެ ރަސޫލާގެ ހުކުމް އޮތްގޮތެއް ބަލައި އެގޮތަށް ޢަމަލުކުރާށެވެ!) ތިޔަބައިމީހުން، ﷲއަށާއި، އާޚިރަތް ދުވަހަށް އީމާންވާ ކަމުގައި ވާނަމައެވެ. އެގޮތް ތިޔަބައިމީހުންނަށް ހެޔޮކަންބޮޑެވެ. އަދި، ނިމުމެއްގެގޮތުން ރީތިކަންވެސް ބޮޑުމެއެވެ.","",""],["₄ سورة النساء","60","أَلَمۡ تَرَ إِلَى ٱلَّذِينَ يَزۡعُمُونَ أَنَّهُمۡ ءَامَنُواْ بِمَآ أُنزِلَ إِلَيۡكَ وَمَآ أُنزِلَ مِن قَبۡلِكَ يُرِيدُونَ أَن يَتَحَاكَمُوٓاْ إِلَى ٱلطَّـٰغُوتِ وَقَدۡ أُمِرُوٓاْ أَن يَكۡفُرُواْ بِهِۦۖ وَيُرِيدُ ٱلشَّيۡطَٰنُ أَن يُضِلَّهُمۡ ضَلَٰلَۢا بَعِيدٗا ٦٠","ألم تر إلى الذين يزعمون أنهم آمنوا بما أنزل إليك وما أنزل من قبلك يريدون أن يتحاكموا إلى الطاغوت وقد أمروا أن يكفروا به ويريد الشيطان أن يضلهم ضلالا بعيدا","ކަލޭގެފާނަށް ބާވައިލައްވާފައިވާ ފޮތަށާއި، ކަލޭގެފާނުންގެ ކުރިން ބާވައިލައްވާފައިވާ ފޮތްތަކަށް، އީމާން ވެގެން ތިބިކަމަށް ބުނާ މީހުން ކަލޭގެފާނު ދެކެވަޑައިނުގަންނަވަމުތޯއެވެ؟ އެއުރެން ހުކުމް ލިބިގަންނާން، އުރެދުންތެރިކަން ބޮޑުފަރާތަށް ދިއުމަށް އެއުރެން އެދެތެވެ. ހަމަކަށަވަރުން، އެފަރާތަށް ކާފިރު ވުމަށް އެއުރެންނަށް އަމުރުކުރައްވާފައިވާ ޙާލު ގައެވެ. އަދި، ޝައިތާނާ އެދެނީ، (ހައްގު މަގުން) ދުރުވެގެންވާ މަގުފުރެދުމަކުން، އެއުރެން މަގުފުރެއްދުމަށެވެ.","",""],["₄ سورة النساء","61","وَإِذَا قِيلَ لَهُمۡ تَعَالَوۡاْ إِلَىٰ مَآ أَنزَلَ ٱللَّهُ وَإِلَى ٱلرَّسُولِ رَأَيۡتَ ٱلۡمُنَٰفِقِينَ يَصُدُّونَ عَنكَ صُدُودٗا ٦١","وإذا قيل لهم تعالوا إلى ما أنزل الله وإلى الرسول رأيت المنافقين يصدون عنك صدودا","އަދި، ﷲ ބާވައިލައްވާފައިވާ ފޮތަށާއި، ރަސޫލާ އަންގަވާ ގޮތަށް ތަބާ ވާން ތިޔަބައިމީހުން އަންނާށޭ ބުނެފިނަމަ، މުނާފިގުން، (ނަފުރަތުވެ) ކަލޭގެފާނަށް ފުރަގަސްދޭތީ ދެކެވަޑައިގަންނަވާނޫއެވެ.","",""],["₄ سورة النساء","62","فَكَيۡفَ إِذَآ أَصَٰبَتۡهُم مُّصِيبَةُۢ بِمَا قَدَّمَتۡ أَيۡدِيهِمۡ ثُمَّ جَآءُوكَ يَحۡلِفُونَ بِٱللَّهِ إِنۡ أَرَدۡنَآ إِلَّآ إِحۡسَٰنٗا وَتَوۡفِيقًا ٦٢","فكيف إذا أصابتهم مصيبة بما قدمت أيديهم ثم جاءوك يحلفون بالله إن أردنا إلا إحسانا وتوفيقا","އަދި، އެއުރެންގެ އަތްތަކުން އިސްކުޅަ ޢަމަލު ތަކެއްގެ ސަބަބުން އެއުރެންނަށް މުސީބަތެއް ޖެހިއްޖިއްޔާ ކޮންފަދަތޯއެވެ؟ ދެން، އެއުރެން އިހްސާން ތެރިވުމާއި، އެކުވެރިކުރުން މެނުވީ ތިމަންމެން ގަސްދެއް ނުކުރަމުއޭ ދަންނަވައި، ﷲ ގަންދީ ހުވާކުރަމުން ކަލޭގެފާނުންގެ އަރިހަށް އާދެއެވެ.","",""],["₄ سورة النساء","63","أُوْلَـٰٓئِكَ ٱلَّذِينَ يَعۡلَمُ ٱللَّهُ مَا فِي قُلُوبِهِمۡ فَأَعۡرِضۡ عَنۡهُمۡ وَعِظۡهُمۡ وَقُل لَّهُمۡ فِيٓ أَنفُسِهِمۡ قَوۡلَۢا بَلِيغٗا ٦٣","أولئك الذين يعلم الله ما في قلوبهم فأعرض عنهم وعظهم وقل لهم في أنفسهم قولا بليغا","އެއުރެންނަކީ، އެއުރެންގެ ހިތްތަކުގައިވާ ގޮތްތައް، ﷲ ދެނެވޮޑިގެންވާ މީހުންނެވެ. ފަހެ، (ކަލޭގެފާނު އެއުރެންނާ އުގޫބާތް ދެއްވުން ފިޔަވައި) ކަލޭގެފާނު ދުރުހެލިވެވަޑައި ގަންނަވާށެވެ! އަދި، އެއުރެންނަށް ވައުޒާއި ނަސޭހަތް އިއްވަވާށެވެ! އަދި، އެއުރެންގެ ނަފްސު ތަކާމެދު އަސަރުކުރާފަދަ ބަލާޣަތް ތެރި ބަސްފުޅަކުން އެއުރެންނާ ވާހަކަފުޅު ދައްކަވާށެވެ!","",""],["₄ سورة النساء","64","وَمَآ أَرۡسَلۡنَا مِن رَّسُولٍ إِلَّا لِيُطَاعَ بِإِذۡنِ ٱللَّهِۚ وَلَوۡ أَنَّهُمۡ إِذ ظَّلَمُوٓاْ أَنفُسَهُمۡ جَآءُوكَ فَٱسۡتَغۡفَرُواْ ٱللَّهَ وَٱسۡتَغۡفَرَ لَهُمُ ٱلرَّسُولُ لَوَجَدُواْ ٱللَّهَ تَوَّابٗا رَّحِيمٗا ٦٤","وما أرسلنا من رسول إلا ليطاع بإذن الله ولو أنهم إذ ظلموا أنفسهم جاءوك فاستغفروا الله واستغفر لهم الرسول لوجدوا الله توابا رحيما","ﷲގެ އިޒުނަ ފުޅާއެކު، ކިޔަމަންވުމަށްޓަކައި މެނުވީ، ތިމަންރަސްކަލާނގެ އެއްވެސް ރަސޫލަކު ނުފޮނުއްވަމެވެ. އަދި، އެއުރެން އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް އަނިޔާވެރިވީހިނދު، ކަލޭގެފާނުގެ އަރިހަށް އެއުރެން އައިސް، ފާފަފުއްސެވުމަށް ﷲގެ ހަޒުރަތަށް ދަންނަވައި އެދުނުނަމަ، އަދި، ރަސޫލާ އެއުރެންނަށް ފާފަފުއްސެވުމަށް އެދިވަޑައިގެން ދުއާކުރެއްވިނަމަ، ގިނަގިނައިން ތައުބާ ގަބޫލުކުރައްވާ ރަޙީމްވަންތަ ކަލަކު ކަމުގައި އެއުރެން ﷲ ދެކޭނެކަން ކަށަވަރެވެ.","",""],["₄ سورة النساء","65","فَلَا وَرَبِّكَ لَا يُؤۡمِنُونَ حَتَّىٰ يُحَكِّمُوكَ فِيمَا شَجَرَ بَيۡنَهُمۡ ثُمَّ لَا يَجِدُواْ فِيٓ أَنفُسِهِمۡ حَرَجٗا مِّمَّا قَضَيۡتَ وَيُسَلِّمُواْ تَسۡلِيمٗا ٦٥","فلا وربك لا يؤمنون حتى يحكموك فيما شجر بينهم ثم لا يجدوا في أنفسهم حرجا مما قضيت ويسلموا تسليما","އެހެންނަކުން ނޫނެވެ! ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ގަންދެއްވައި ވަހީކުރައްވަމެވެ. އެއުރެންގެ މެދުގައި އުފެދިފައިވާ ދެކޮޅުވެރިކަމުގައި، ކަލޭގެފާނު ހުކުމްވެރި ކޮށްފުމަށް ދާނދެން، އެއުރެން އީމާނެއް ނުވާނެތެވެ. އެހިނދު، ކަލޭގެފާނު ނިޔާކުރެއްވި ގޮތާމެދު އެއުރެންގެ ހިތްތަކުގައި، ދަތިކަމެއް ވާކަމުގައި އެއުރެން ނުދެކޭނެތެވެ. އަދި އެއުރެން (އެ ނިޔާއަށް) ފުރިހަމަވެގެންވާ ކިޔަމަންވުމަކުން ކިޔަމަންވާނެތެވެ.","",""],["₄ سورة النساء","66","وَلَوۡ أَنَّا كَتَبۡنَا عَلَيۡهِمۡ أَنِ ٱقۡتُلُوٓاْ أَنفُسَكُمۡ أَوِ ٱخۡرُجُواْ مِن دِيَٰرِكُم مَّا فَعَلُوهُ إِلَّا قَلِيلٞ مِّنۡهُمۡۖ وَلَوۡ أَنَّهُمۡ فَعَلُواْ مَا يُوعَظُونَ بِهِۦ لَكَانَ خَيۡرٗا لَّهُمۡ وَأَشَدَّ تَثۡبِيتٗا ٦٦","ولو أنا كتبنا عليهم أن اقتلوا أنفسكم أو اخرجوا من دياركم ما فعلوه إلا قليل منهم ولو أنهم فعلوا ما يوعظون به لكان خيرا لهم وأشد تثبيتا","އަދި، ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތައް ގަތުލުކުރާށޭ ނުވަތަ ތިޔަބައިމީހުންގެ ގޯތިގެދޮރުން ނުކުންނާށޭ އަންގަވައި، އެކަން އެއުރެންގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ފަރުޟުކުރެއްވިނަމަ، އޭގެތެރެއިން މަދުބަޔަކު މެނުވީ އެކަންތަކެއް ނުކުޅައީހެވެ. އަދި، އެއުރެންނަށް އެކަމާމެދު ވައުޒު އިއްވަވާ ކަންތައް އެއުރެން ކުޅަނަމަ، އެއުރެންނަށް ހެޔޮކަން މާބޮޑުވީހެވެ. އަދި، ޘާބިތުވެ ތިބުމުގައި ގަދަފަދަކަން ބޮޑުވީސްމެއެވެ.","",""],["₄ سورة النساء","67","وَإِذٗا لَّأٓتَيۡنَٰهُم مِّن لَّدُنَّآ أَجۡرًا عَظِيمٗا ٦٧","وإذا لآتيناهم من لدنا أجرا عظيما","އަދި، އެހެންވީނަމަ، ތިމަންރަސްކަލާނގެ ހަޒުރަތުން އެއުރެންނަށް ބޮޑުވެގެންވާ ދަރުމައެއް ދެއްވީމުހެވެ.","",""],["₄ سورة النساء","68","وَلَهَدَيۡنَٰهُمۡ صِرَٰطٗا مُّسۡتَقِيمٗا ٦٨","ولهديناهم صراطا مستقيما","އަދި، ސީދާވެގެންވާ ތެދުމަގަކަށް އެއުރެންނަށް މަގު ދެއްކެވީމުހެވެ.","",""],["₄ سورة النساء","69","وَمَن يُطِعِ ٱللَّهَ وَٱلرَّسُولَ فَأُوْلَـٰٓئِكَ مَعَ ٱلَّذِينَ أَنۡعَمَ ٱللَّهُ عَلَيۡهِم مِّنَ ٱلنَّبِيِّـۧنَ وَٱلصِّدِّيقِينَ وَٱلشُّهَدَآءِ وَٱلصَّـٰلِحِينَۚ وَحَسُنَ أُوْلَـٰٓئِكَ رَفِيقٗا ٦٩","ومن يطع الله والرسول فأولئك مع الذين أنعم الله عليهم من النبيين والصديقين والشهداء والصالحين وحسن أولئك رفيقا","ﷲއަށާއި، ރަސޫލާއަށް ކިޔަމަންވާ މީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެންވަނީ، ﷲ އެބަޔެއްގެ މައްޗަށް ނިއުމަތް ދެއްވި މީހުންކަމުގައިވާ ނަބިއްޔުންނާއި، ޞިއްދީގްނާއި، ޝަހީދްނާއި، ސާލިހުންނާ އެކުގައެވެ. އެބޭކަލުންނީ އެކުވެރިން ކަމުގައިވުމަށް ހާދަ ރަނގަޅު ބަޔެކެވެ.","",""],["₄ سورة النساء","70","ذَٰلِكَ ٱلۡفَضۡلُ مِنَ ٱللَّهِۚ وَكَفَىٰ بِٱللَّهِ عَلِيمٗا ٧٠","ذلك الفضل من الله وكفى بالله عليما","އެ ފަޟްލު ވަންތަކަން ވަނީ، ﷲގެ ހަޒުރަތުންނެވެ. މޮޅަށް ދެނެވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ފުދެއެވެ.","",""],["₄ سورة النساء","71","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ خُذُواْ حِذۡرَكُمۡ فَٱنفِرُواْ ثُبَاتٍ أَوِ ٱنفِرُواْ جَمِيعٗا ٧١","يا أيها الذين آمنوا خذوا حذركم فانفروا ثبات أو انفروا جميعا","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން (އަދުއްވުންނާ ހަނގުރާމަ ކުރުމުގައި) ރައްކާތެރި ކަމުގައި ހިފާށެވެ! އަދި، ބައިބަޔަށް ތިޔަބައިމީހުން ހަނގުރާމަޔަށް ނުކުންނާށެވެ! ނުވަތަ، އެންމެން އެކުގައި ތިޔަބައިމީހުން ހަނގުރާމަޔަށް ނުކުންނާށެވެ!","",""],["₄ سورة النساء","72","وَإِنَّ مِنكُمۡ لَمَن لَّيُبَطِّئَنَّ فَإِنۡ أَصَٰبَتۡكُم مُّصِيبَةٞ قَالَ قَدۡ أَنۡعَمَ ٱللَّهُ عَلَيَّ إِذۡ لَمۡ أَكُن مَّعَهُمۡ شَهِيدٗا ٧٢","وإن منكم لمن ليبطئن فإن أصابتكم مصيبة قال قد أنعم الله علي إذ لم أكن معهم شهيدا","ހަމަކަށަވަރުން، ހަނގުރާމަޔަށް ނުކުތުމުގައި ފަސްޖެހި، އަދި އެހެން މީހުން ފަސްޖެހުމަށް ބާރުއަޅާ މީހަކު، ތިޔަބައިމީހުންގެ ތެރެއިން ވާކަން ކަށަވަރެވެ. ފަހެ، ތިޔަބައިމީހުންނަށް މުސީބަތެއް ޖެހިއްޖެނަމަ، އެމީހަކު ބުނެތެވެ. ހަމަކަށަވަރުން، ﷲ ތިމަންނާޔަށްވަނީ ނިއުމަތް ދެއްވާފައެވެ. އެހެނީ، ތިމަން އެއުރެންނާއެކު ހަނގުރާމަޔަށް ޙާޒިރުު ވީ މީހަކު ކަމުގައި ނުވަމެވެ.","",""],["₄ سورة النساء","73","وَلَئِنۡ أَصَٰبَكُمۡ فَضۡلٞ مِّنَ ٱللَّهِ لَيَقُولَنَّ كَأَن لَّمۡ تَكُنۢ بَيۡنَكُمۡ وَبَيۡنَهُۥ مَوَدَّةٞ يَٰلَيۡتَنِي كُنتُ مَعَهُمۡ فَأَفُوزَ فَوۡزًا عَظِيمٗا ٧٣","ولئن أصابكم فضل من الله ليقولن كأن لم تكن بينكم وبينه مودة يا ليتني كنت معهم فأفوز فوزا عظيما","އަދި، ﷲގެ ހަޒުރަތުން، ތިޔަބައިމީހުންނަށް ފަޟްލު ވަންތަކަމެއް ލިބިއްޖެނަމަ، ހަމަކަށަވަރުން، އެމީހަކު ބުނާނެތެވެ. އޭ ސަހަރޯއެވެ! އެއުރެންނާ އެކުގައި ތިމަންވެސް ހަނގުރާމައިގައި ވީނަމަ ކިހާރަނގަޅުވީސް ހެއްޔެވެ؟ ފަހެ، އޭރުން ބޮޑުވެގެންވާ ނަސީބަކުން ތިމަންނާއަށް ނަސީބު ލިބޭނެއެވެ. (މިފަދައިން ބުނާއިރު) އެމީހަކާ ތިޔަބައިމީހުންނާ ދެމެދުގައި އެކުވެރިކަމެއް ރައްޓެހި ކަމެއްވެސް ނުވާކަހަލައެވެ.","",""],["₄ سورة النساء","74","۞فَلۡيُقَٰتِلۡ فِي سَبِيلِ ٱللَّهِ ٱلَّذِينَ يَشۡرُونَ ٱلۡحَيَوٰةَ ٱلدُّنۡيَا بِٱلۡأٓخِرَةِۚ وَمَن يُقَٰتِلۡ فِي سَبِيلِ ٱللَّهِ فَيُقۡتَلۡ أَوۡ يَغۡلِبۡ فَسَوۡفَ نُؤۡتِيهِ أَجۡرًا عَظِيمٗا ٧٤","فليقاتل في سبيل الله الذين يشرون الحياة الدنيا بالآخرة ومن يقاتل في سبيل الله فيقتل أو يغلب فسوف نؤتيه أجرا عظيما","އާޚިރަތަށް ދުނިޔޭގެ ދިރިއުޅުން ދޫކޮށްލާ މީހުން، ﷲގެ މަގުގައި ހަނގުރާމަކުރާ ހުށިކަމެވެ! ﷲގެ މަގުގައި ހަނގުރާމަކޮށް، ގަތުލު ވާމީހާ، ނުވަތަ ދުޝްމަނުން ބަލިކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، ތިމަންރަސްކަލާނގެ އެމީހަކަށް ބޮޑުވެގެންވާ ދަރުމައެއް ދެއްވާހުށީމެވެ.","",""],["₄ سورة النساء","75","وَمَا لَكُمۡ لَا تُقَٰتِلُونَ فِي سَبِيلِ ٱللَّهِ وَٱلۡمُسۡتَضۡعَفِينَ مِنَ ٱلرِّجَالِ وَٱلنِّسَآءِ وَٱلۡوِلۡدَٰنِ ٱلَّذِينَ يَقُولُونَ رَبَّنَآ أَخۡرِجۡنَا مِنۡ هَٰذِهِ ٱلۡقَرۡيَةِ ٱلظَّالِمِ أَهۡلُهَا وَٱجۡعَل لَّنَا مِن لَّدُنكَ وَلِيّٗا وَٱجۡعَل لَّنَا مِن لَّدُنكَ نَصِيرًا ٧٥","وما لكم لا تقاتلون في سبيل الله والمستضعفين من الرجال والنساء والولدان الذين يقولون ربنا أخرجنا من هذه القرية الظالم أهلها واجعل لنا من لدنك وليا واجعل لنا من لدنك نصيرا","އަދި، ﷲގެ މަގުގައްޔާއި، އަދި ފިރިހެނުންނާއި، އަންހެނުންނާއި، ކުޑަކުދިންގެ ތެރެއިން، ނިކަމެތި ވެގެންވާ މީހުން ސަލާމަތްކުރުމުގެ މަގުގައި، ތިޔަބައިމީހުން ހަނގުރާމަ ނުކުރާންވީ ކީއްވެގެން ހެއްޔެވެ؟ އެއުރެންނަކީ، (މިފަދައިން) ދުއާކުރާ މީހުންނެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އެރަށުގެ އަހުލުވެރިން އަނިޔާވެރިވެގެންވާ މި ރަށުން އަޅަމެން ނެރުއްވައިފާނދޭވެ! އަދި، އިބަރަސްކަލާނގެ ހަޒުރަތުން ވާގިވެރިޔަކު އަޅަމެންނަށް ލައްވައިފާނދޭވެ! އަދި، އިބަރަސްކަލާނގެ ހަޒުރަތުން ނަސްރުވެރިޔަކު އަޅަމެންނަށް ލައްވައިފާނދޭވެ!","",""],["₄ سورة النساء","76","ٱلَّذِينَ ءَامَنُواْ يُقَٰتِلُونَ فِي سَبِيلِ ٱللَّهِۖ وَٱلَّذِينَ كَفَرُواْ يُقَٰتِلُونَ فِي سَبِيلِ ٱلطَّـٰغُوتِ فَقَٰتِلُوٓاْ أَوۡلِيَآءَ ٱلشَّيۡطَٰنِۖ إِنَّ كَيۡدَ ٱلشَّيۡطَٰنِ كَانَ ضَعِيفًا ٧٦","الذين آمنوا يقاتلون في سبيل الله والذين كفروا يقاتلون في سبيل الطاغوت فقاتلوا أولياء الشيطان إن كيد الشيطان كان ضعيفا","އީމާންވި މީހުން ﷲގެ މަގުގައި ހަނގުރާމަކުރެތެވެ. އަދި، ކާފިރުވި މީހުން ޝައިތާނާގެ މަގުގައި ހަނގުރާމަކުރެތެވެ. ފަހެ، ތިޔަބައިމީހުން ޝައިތާނާގެ ވާގިވެރިންނާ ހަނގުރާމަކުރާށެވެ! ހަމަކަށަވަރުން، ޝައިތާނާގެ ކެހިވެރިކަންވަނީ ނިކަމެތިވެގެންނެވެ.","",""],["₄ سورة النساء","77","أَلَمۡ تَرَ إِلَى ٱلَّذِينَ قِيلَ لَهُمۡ كُفُّوٓاْ أَيۡدِيَكُمۡ وَأَقِيمُواْ ٱلصَّلَوٰةَ وَءَاتُواْ ٱلزَّكَوٰةَ فَلَمَّا كُتِبَ عَلَيۡهِمُ ٱلۡقِتَالُ إِذَا فَرِيقٞ مِّنۡهُمۡ يَخۡشَوۡنَ ٱلنَّاسَ كَخَشۡيَةِ ٱللَّهِ أَوۡ أَشَدَّ خَشۡيَةٗۚ وَقَالُواْ رَبَّنَا لِمَ كَتَبۡتَ عَلَيۡنَا ٱلۡقِتَالَ لَوۡلَآ أَخَّرۡتَنَآ إِلَىٰٓ أَجَلٖ قَرِيبٖۗ قُلۡ مَتَٰعُ ٱلدُّنۡيَا قَلِيلٞ وَٱلۡأٓخِرَةُ خَيۡرٞ لِّمَنِ ٱتَّقَىٰ وَلَا تُظۡلَمُونَ فَتِيلًا ٧٧","ألم تر إلى الذين قيل لهم كفوا أيديكم وأقيموا الصلاة وآتوا الزكاة فلما كتب عليهم القتال إذا فريق منهم يخشون الناس كخشية الله أو أشد خشية وقالوا ربنا لم كتبت علينا القتال لولا أخرتنا إلى أجل قريب قل متاع الدنيا قليل والآخرة خير لمن اتقى ولا تظلمون فتيلا","ތިޔަބައިމީހުންގެ އަތްތައް (ހަނގުރާމައިން) އެއްކިބާކުރާށޭ، އަދި، ތިޔަބައިމީހުން ނަމާދު ގާއިމު ކޮށް، ޒަކާތް ދީ، އުޅޭށޭ އަންގަވާފައިވާ މީހުން، ކަލޭގެފާނު ދެކެވަޑައި ނުގަންނަވަމުތޯއެވެ؟ ދެންފަހެ، ހަނގުރާމަކުރުން އެއުރެންގެ މައްޗަށް ފަރުޟުކުރެއްވި ހިނދު، އެހާރުން އޭގެތެރެއިން ބަޔަކު ﷲއަށް ބިރުވެތިވާފަދައިން، ނުވަތަ، އެއަށްވުރެވެސް ގަދަ ބިރުވެތިވުމަކުން، މީސްތަކުންދެކެ ބިރުވެތިވެތެވެ. އަދި، އެއުރެން ބުނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! އިބަރަސްކަލާނގެ އަޅަމެންގެ މައްޗަށް ހަނގުރާމަކުރުން ފަރުޟުކުރެއްވީ ކީއްވެގެންތޯއެވެ؟ ކައިރި މުއްދަތަކަށް އަޅަމެންނަށް ފަސްކޮށްދެއްވިނަމަ، ކޮންފަދަތޯއެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ދުނިޔޭގެ އުފަލަކީ ކުޑަވަގުތުކޮޅެއްގެ ކަމެކެވެ. އަދި، ތަގުވާވެރިވި މީހަކަށް އާޚިރަތް ހެޔޮކަން ބޮޑެވެ. އަދި، ތިޔަބައިމީހުންނަށް ކިތަންމެ ކުޑަމިންވަރަކުންވެސް ބޭއިންސާފެއް ނުކުރައްވާހުށްޓެވެ.","",""],["₄ سورة النساء","78","أَيۡنَمَا تَكُونُواْ يُدۡرِككُّمُ ٱلۡمَوۡتُ وَلَوۡ كُنتُمۡ فِي بُرُوجٖ مُّشَيَّدَةٖۗ وَإِن تُصِبۡهُمۡ حَسَنَةٞ يَقُولُواْ هَٰذِهِۦ مِنۡ عِندِ ٱللَّهِۖ وَإِن تُصِبۡهُمۡ سَيِّئَةٞ يَقُولُواْ هَٰذِهِۦ مِنۡ عِندِكَۚ قُلۡ كُلّٞ مِّنۡ عِندِ ٱللَّهِۖ فَمَالِ هَـٰٓؤُلَآءِ ٱلۡقَوۡمِ لَا يَكَادُونَ يَفۡقَهُونَ حَدِيثٗا ٧٨","أينما تكونوا يدرككم الموت ولو كنتم في بروج مشيدة وإن تصبهم حسنة يقولوا هذه من عند الله وإن تصبهم سيئة يقولوا هذه من عندك قل كل من عند الله فمال هؤلاء القوم لا يكادون يفقهون حديثا","އުސްވެގެންވާ ގަދަފަދަ ކިއްލާތަކެއްގެ ތެރޭގައި ތިޔަބައިމީހުން ތިބިކަމުގައިވިޔަސް، ތިޔަބައިމީހުން ތިބި ކޮންމެ ތަނަކުން މަރު، ތިޔަބައިމީހުން އަތުލާނެތެވެ. އެއުރެންނަށް ހެޔޮގޮތެއް މެދުވެރިވެއްޖެނަމަ، މިއީ، ﷲގެ ހަޒުރަތުން އައިކަމެކޭ އެއުރެން ބުނެތެވެ. އަދި، އެއުރެންނަށް ދެރަގޮތެއް މެދުވެރިވެއްޖެނަމަ، މިއީ، ކަލޭގެފާނުންގެ ފަރާތުން އައިކަމެކޭ އެއުރެން ބުނެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ކޮންމެކަމަކީވެސް، ﷲގެ ހަޒުރަތުން އަންނަ ކަމެކެވެ. ފަހެ، މިބައިމީހުންނަށް އެއްވެސް ވާހަކައެއް ވިސްނޭން ގާތްވެސްނުވެ އެތިބީ ކީއްވެފައި ބާވައެވެ؟","",""],["₄ سورة النساء","79","مَّآ أَصَابَكَ مِنۡ حَسَنَةٖ فَمِنَ ٱللَّهِۖ وَمَآ أَصَابَكَ مِن سَيِّئَةٖ فَمِن نَّفۡسِكَۚ وَأَرۡسَلۡنَٰكَ لِلنَّاسِ رَسُولٗاۚ وَكَفَىٰ بِٱللَّهِ شَهِيدٗا ٧٩","ما أصابك من حسنة فمن الله وما أصابك من سيئة فمن نفسك وأرسلناك للناس رسولا وكفى بالله شهيدا","ތިބާޔަށް ލިބިއްޖެ ހެޔޮކަމަކީ، ފަހެ، ﷲގެ ހަޒުރަތުން އައިކަމެކެވެ. އަދި، ތިބާޔަށް ލިބިއްޖެ ދެރަކަމަކީ، ފަހެ، ތިބާގެ އަމިއްލަ ނަފްސުގެ ފަރާތުން އައިކަމެކެވެ. ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު މީސްތަކުންގެ ގާތަށް ފޮނުއްވާފައިވަނީ، ރަސޫލަކު ކަމުގައެވެ. ހެކިވެރިޔަކު ކަމުގައި ﷲ ފުދެއެވެ.","",""],["₄ سورة النساء","80","مَّن يُطِعِ ٱلرَّسُولَ فَقَدۡ أَطَاعَ ٱللَّهَۖ وَمَن تَوَلَّىٰ فَمَآ أَرۡسَلۡنَٰكَ عَلَيۡهِمۡ حَفِيظٗا ٨٠","من يطع الرسول فقد أطاع الله ومن تولى فما أرسلناك عليهم حفيظا","ރަސޫލާއަށް ކިޔަމަންވާ މީހާ، ފަހެ، ހަމަކަށަވަރުން ﷲއަށް ކިޔަމަންވެއްޖެއެވެ. އަދި، ފުރަގަސް ދީފި މީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންގެ ކަންތައްތައް ބަލަހައްޓަވަން ހުންނެވި ބޭކަލަކު ކަމުގައި ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ނުފޮނުއްވަމެވެ.","",""],["₄ سورة النساء","81","وَيَقُولُونَ طَاعَةٞ فَإِذَا بَرَزُواْ مِنۡ عِندِكَ بَيَّتَ طَآئِفَةٞ مِّنۡهُمۡ غَيۡرَ ٱلَّذِي تَقُولُۖ وَٱللَّهُ يَكۡتُبُ مَا يُبَيِّتُونَۖ فَأَعۡرِضۡ عَنۡهُمۡ وَتَوَكَّلۡ عَلَى ٱللَّهِۚ وَكَفَىٰ بِٱللَّهِ وَكِيلًا ٨١","ويقولون طاعة فإذا برزوا من عندك بيت طائفة منهم غير الذي تقول والله يكتب ما يبيتون فأعرض عنهم وتوكل على الله وكفى بالله وكيلا","އެއުރެން ބުނެތެވެ. ތިމަންމެން ކިޔަމަންވަމުއެވެ. ފަހެ، އެއުރެން ކަލޭގެފާނުގެ އަރިހުން ނުކުމެއްޖެނަމަ، އޭގެތެރެއިން ބަޔަކު ކަލޭގެފާނު ވިދާޅުވާގޮތް ނޫންގޮތަކަށް ރާވައެވެ. އެއުރެން ރާވާގޮތް ﷲ ލިޔުއްވަތެވެ. ފަހެ، ކަލޭގެފާނު އެއުރެންނާ ދުރުހެލިވެ ވަޑައިގަންނަވާށެވެ! އަދި، ﷲއަށް ވަކީލުކުރައްވާށެވެ! ވަކީލަކު ކަމުގައި ﷲ ފުދެއެވެ.","",""],["₄ سورة النساء","82","أَفَلَا يَتَدَبَّرُونَ ٱلۡقُرۡءَانَۚ وَلَوۡ كَانَ مِنۡ عِندِ غَيۡرِ ٱللَّهِ لَوَجَدُواْ فِيهِ ٱخۡتِلَٰفٗا كَثِيرٗا ٨٢","أفلا يتدبرون القرآن ولو كان من عند غير الله لوجدوا فيه اختلافا كثيرا","ފަހެ، ގުރްއާނާމެދު އެއުރެން ވިސްނައި ފިކުރު ނުކުރަނީހެއްޔެވެ؟ އެ ގުރްއާނަކީ، ﷲ ނޫން އެހެން ފަރާތަކުން އައި އެއްޗެއް ކަމުގައިވީނަމަ، ގިނަވެގެންވާ ތަފާތުތައް އެއިން އެއުރެންނަށް ފެނުނީހެވެ.","",""],["₄ سورة النساء","83","وَإِذَا جَآءَهُمۡ أَمۡرٞ مِّنَ ٱلۡأَمۡنِ أَوِ ٱلۡخَوۡفِ أَذَاعُواْ بِهِۦۖ وَلَوۡ رَدُّوهُ إِلَى ٱلرَّسُولِ وَإِلَىٰٓ أُوْلِي ٱلۡأَمۡرِ مِنۡهُمۡ لَعَلِمَهُ ٱلَّذِينَ يَسۡتَنۢبِطُونَهُۥ مِنۡهُمۡۗ وَلَوۡلَا فَضۡلُ ٱللَّهِ عَلَيۡكُمۡ وَرَحۡمَتُهُۥ لَٱتَّبَعۡتُمُ ٱلشَّيۡطَٰنَ إِلَّا قَلِيلٗا ٨٣","وإذا جاءهم أمر من الأمن أو الخوف أذاعوا به ولو ردوه إلى الرسول وإلى أولي الأمر منهم لعلمه الذين يستنبطونه منهم ولولا فضل الله عليكم ورحمته لاتبعتم الشيطان إلا قليلا","އަދި، އެއުރެންގެ ގާތަށް އަމާންކަމުގެ ތެރެއިން، ނުވަތަ ބިރުވެރިކަމުގެ ތެރެއިން ކަމެއް އަތުވެއްޖެނަމަ (އެބަހީ: ހަނގުރާމައިގައި ނަސްރު ލިބުން ނުވަތަ ބަލިވުން ފަދަ ޚަބަރެއް އެއުރެންނަށް ލިބިއްޖެނަމަ) އެކަމެއް (އެންމެންގެ ތެރެޔަށް) ފަތުރާލައެވެ. އަދި، ރަސޫލާގެ އަރިހަށާއި އެއުރެންގެ ތެރެއިން އަމުރުވެރިންގެ ގާތަށް އެކަމެއް ރައްދުކުޅަނަމަ، އޭގެތެރެއިން، އެފަދަ ކަންތަކުގެ ހަގީގަތްތައް ހޯދައިގަންނަ މީހުންނަށް، އެކަމެއް އެނގުނީސްކަން ކަށަވަރެވެ. ﷲގެ ފަޟްލު ވަންތަކަމާއި، އެކަލާނގެ ރަހުމަތް ނުވާނަމަ، ތިޔަބައިމީހުންގެ ތެރެއިން މަދުބަޔަކު މެނުވީ ޝައިތާނާއަށް ތަބާ ވެއްޖައީހެވެ.","",""],["₄ سورة النساء","84","فَقَٰتِلۡ فِي سَبِيلِ ٱللَّهِ لَا تُكَلَّفُ إِلَّا نَفۡسَكَۚ وَحَرِّضِ ٱلۡمُؤۡمِنِينَۖ عَسَى ٱللَّهُ أَن يَكُفَّ بَأۡسَ ٱلَّذِينَ كَفَرُواْۚ وَٱللَّهُ أَشَدُّ بَأۡسٗا وَأَشَدُّ تَنكِيلٗا ٨٤","فقاتل في سبيل الله لا تكلف إلا نفسك وحرض المؤمنين عسى الله أن يكف بأس الذين كفروا والله أشد بأسا وأشد تنكيلا","ފަހެ، ﷲގެ މަގުގައި ކަލޭގެފާނު ހަނގުރާމަ ކުރައްވާށެވެ! ކަލޭގެފާނުންގެ އަމިއްލަ ނަފްސަށް މެނުވީ ކަލޭގެފާނަކަށް ތަކުލީފެއް ނުޖައްސަވާހުށްޓެވެ. އަދި، (ހަނގުރާމަކުރުމުގެ މައްޗަށް) މުއުމިނުންނަށް ކަލޭގެފާނު ހިތްވަރު ދެއްވާށެވެ! ކާފިރުވި މީހުންގެ ބާރު، ﷲ ނެތިކުރެއްވުން ގާތެވެ. އަދި، ބާރުވެރިކަމުގެ ގޮތުން ﷲ ގަދަފަދަ ވަންތަކަން ބޮޑެވެ. އަދި، އަޒާބު ދެއްވުމުގައިވެސް ގަދަފަދަވަންތަކަން ބޮޑުމެއެވެ.","",""],["₄ سورة النساء","85","مَّن يَشۡفَعۡ شَفَٰعَةً حَسَنَةٗ يَكُن لَّهُۥ نَصِيبٞ مِّنۡهَاۖ وَمَن يَشۡفَعۡ شَفَٰعَةٗ سَيِّئَةٗ يَكُن لَّهُۥ كِفۡلٞ مِّنۡهَاۗ وَكَانَ ٱللَّهُ عَلَىٰ كُلِّ شَيۡءٖ مُّقِيتٗا ٨٥","من يشفع شفاعة حسنة يكن له نصيب منها ومن يشفع شفاعة سيئة يكن له كفل منها وكان الله على كل شيء مقيتا","ހެޔޮ ޝަފާއަތަކުން ޝަފާއަތް ތެރިވާ މީހާޔަށް އޭގެ (ދަރުމައިން) ބައެއްވެއެވެ. އަދި، ނުބައި ޝަފާއަތަކުން ޝަފާއަތް ތެރިވާ މީހާޔަށް އޭގެ (ފާފައިން) ބައެއްވެއެވެ. ކޮންމެ ކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","86","وَإِذَا حُيِّيتُم بِتَحِيَّةٖ فَحَيُّواْ بِأَحۡسَنَ مِنۡهَآ أَوۡ رُدُّوهَآۗ إِنَّ ٱللَّهَ كَانَ عَلَىٰ كُلِّ شَيۡءٍ حَسِيبًا ٨٦","وإذا حييتم بتحية فحيوا بأحسن منها أو ردوها إن الله كان على كل شيء حسيبا","ތިޔަބައިމީހުންނަށް އެއްވެސްކަހަލަ ސަލާމަކުން ސަލާމް ކޮށްފިނަމަ، އެއަށްވުރެ ރިވެތި ސަލާމަކުން ތިޔަބައިމީހުން ސަލާމްކުރާށެވެ! ނުވަތަ އެ ސަލާމް ރައްދުކުރާށެވެ! ހަމަކަށަވަރުން، ކޮންމެ ކަމެއްގެ ހިސާބު ބައްލަވާ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","87","ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَۚ لَيَجۡمَعَنَّكُمۡ إِلَىٰ يَوۡمِ ٱلۡقِيَٰمَةِ لَا رَيۡبَ فِيهِۗ وَمَنۡ أَصۡدَقُ مِنَ ٱللَّهِ حَدِيثٗا ٨٧","الله لا إله إلا هو ليجمعنكم إلى يوم القيامة لا ريب فيه ومن أصدق من الله حديثا","ﷲއީ، އެކަލާނގެ ފިޔަވައި (ހައްގު ވެގެން އަޅުކަމެއްވެވޭ) އިލާހަކުނުވާ ރަސްކަލާނގެއެވެ. ގިޔާމަތް ދުވަހުން، އެކަލާނގެ ތިޔަބައިމީހުން އެއްކުރައްވާނެކަން ކަށަވަރެވެ. އެކަމާމެދަކު ޝައްކެއް ނެތެވެ. ބަސްބުނުމުގައި ﷲއަށްވުރެ ތެދުވެރިކަންބޮޑީ ކާކުހެއްޔެވެ؟","",""],["₄ سورة النساء","88","۞فَمَا لَكُمۡ فِي ٱلۡمُنَٰفِقِينَ فِئَتَيۡنِ وَٱللَّهُ أَرۡكَسَهُم بِمَا كَسَبُوٓاْۚ أَتُرِيدُونَ أَن تَهۡدُواْ مَنۡ أَضَلَّ ٱللَّهُۖ وَمَن يُضۡلِلِ ٱللَّهُ فَلَن تَجِدَ لَهُۥ سَبِيلٗا ٨٨","فما لكم في المنافقين فئتين والله أركسهم بما كسبوا أتريدون أن تهدوا من أضل الله ومن يضلل الله فلن تجد له سبيلا","ފަހެ، މުނާފިގުންނާމެދުގައި، ތިޔަބައިމީހުން ދެބަޔަކަށް ބެހިގެންދާންވީ ކީއްވެގެންހެއްޔެވެ؟ އެއުރެންކުޅަ ޢަމަލުތަކުގެ ސަބަބުން، ﷲއެއުރެން ކާފިރުކަމުގެ ތެރެޔަށް ރައްދުކުރައްވާފައިވެއެވެ. ﷲ މަގުފުރައްދަވާފައިވާ މީހަކަށް ތެދުމަގު ދައްކަން ތިޔަބައިމީހުން އެދެނީހެއްޔެވެ؟ ﷲ މަގުފުރައްދަވާ މީހާ، (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް ތެދުމަގު ދައްކަވާނެ މަގެއް ކަލޭގެފާނަކަށް ފެނިވަޑައެއް ނުގަންނަވާނެތެވެ.","",""],["₄ سورة النساء","89","وَدُّواْ لَوۡ تَكۡفُرُونَ كَمَا كَفَرُواْ فَتَكُونُونَ سَوَآءٗۖ فَلَا تَتَّخِذُواْ مِنۡهُمۡ أَوۡلِيَآءَ حَتَّىٰ يُهَاجِرُواْ فِي سَبِيلِ ٱللَّهِۚ فَإِن تَوَلَّوۡاْ فَخُذُوهُمۡ وَٱقۡتُلُوهُمۡ حَيۡثُ وَجَدتُّمُوهُمۡۖ وَلَا تَتَّخِذُواْ مِنۡهُمۡ وَلِيّٗا وَلَا نَصِيرًا ٨٩","ودوا لو تكفرون كما كفروا فتكونون سواء فلا تتخذوا منهم أولياء حتى يهاجروا في سبيل الله فإن تولوا فخذوهم واقتلوهم حيث وجدتموهم ولا تتخذوا منهم وليا ولا نصيرا","އެއުރެން ކާފިރުވި ފަދައިން، ތިޔަބައިމީހުންވެސް ކާފިރު ވާނެ ނަމައޭ ހިތައި އެކަމަށް އެއުރެން އެދުނޫއެވެ. އޭރުން ތިޔަބައިމީހުން (އެއުރެންނާ) ހަމަހަމަވެދާނެތެވެ. ފަހެ، އެއުރެންގެ ތެރެއިން އެހީތެރިން ތިޔަބައިމީހުން ނުހިފާށެވެ! (އެއީ) އެއުރެން ﷲގެ މަގުގައި ހިޖުރަ ކޮށްފުމަށް ދާނދެނެވެ. ފަހެ، އެއުރެން ފުރަގަސްދީފިނަމަ، ތިޔަބައިމީހުންނަށް އެއުރެން ފެނުނު ކޮންމެ ތަނަކުން އެއުރެން އަތުލާށެވެ! އަދި، އެއުރެން ގަތުލުކުރާށެވެ! އަދި، އެއުރެންގެ ތެރެއިން އެހީތެރިޔަކުވެސް އަދި، ނަސްރުވެރިޔަކުވެސް ތިޔަބައިމީހުން ނުހިފާށެވެ!","",""],["₄ سورة النساء","90","إِلَّا ٱلَّذِينَ يَصِلُونَ إِلَىٰ قَوۡمِۭ بَيۡنَكُمۡ وَبَيۡنَهُم مِّيثَٰقٌ أَوۡ جَآءُوكُمۡ حَصِرَتۡ صُدُورُهُمۡ أَن يُقَٰتِلُوكُمۡ أَوۡ يُقَٰتِلُواْ قَوۡمَهُمۡۚ وَلَوۡ شَآءَ ٱللَّهُ لَسَلَّطَهُمۡ عَلَيۡكُمۡ فَلَقَٰتَلُوكُمۡۚ فَإِنِ ٱعۡتَزَلُوكُمۡ فَلَمۡ يُقَٰتِلُوكُمۡ وَأَلۡقَوۡاْ إِلَيۡكُمُ ٱلسَّلَمَ فَمَا جَعَلَ ٱللَّهُ لَكُمۡ عَلَيۡهِمۡ سَبِيلٗا ٩٠","إلا الذين يصلون إلى قوم بينكم وبينهم ميثاق أو جاءوكم حصرت صدورهم أن يقاتلوكم أو يقاتلوا قومهم ولو شاء الله لسلطهم عليكم فلقاتلوكم فإن اعتزلوكم فلم يقاتلوكم وألقوا إليكم السلم فما جعل الله لكم عليهم سبيلا","ތިޔަބައިމީހުންނާ އެބަޔަކާ މެދުގައި އަހުދެއް އޮތް ބަޔެއްގެ ގާތަށް ޙިމާޔަތް ތެރިކަން އެދި ދާބަޔަކު މެނުވީއެވެ. ނުވަތަ، ތިޔަބައިމީހުންނާ ހަނގުރާމަކުރުމަށް ނުވަތަ އެއުރެންގެ ގައުމުގެމީހުންނާ ހަނގުރާމަކުރުމަށް އެއުރެންގެ ހިތްތައް ދަތިވެގެން ތިޔަބައިމީހުންގެ ގާތަށް އައިބަޔަކު މެނުވީއެވެ. ﷲ އިރާދަކުރެއްވިނަމަ، އެކަލާނގެ ތިޔަބައިމީހުންގެ މައްޗަށް އެއުރެން ފާކުރައްވައިފީސްކަން ކަށަވަރެވެ. އަދި، ތިޔަބައިމީހުންނާ ހަނގުރާމަކުރީސްކަން ކަށަވަރެވެ. ފަހެ، އެއުރެން ތިޔަބައިމީހުންނާ ވަކިވެ، ތިޔަބައިމީހުންނާ ހަނގުރާމަނުކޮށް އަދި، ތިޔަބައިމީހުންނަށް އެއުރެން ތަސްލީމް ކޮށްފިނަމަ، ފަހެ، އެއުރެންގެ މައްޗަށް ތިޔަބައިމީހުންނަކަށް ﷲ މަގެއް ލައްވާފައެއް ނުވެއެވެ.","",""],["₄ سورة النساء","91","سَتَجِدُونَ ءَاخَرِينَ يُرِيدُونَ أَن يَأۡمَنُوكُمۡ وَيَأۡمَنُواْ قَوۡمَهُمۡ كُلَّ مَا رُدُّوٓاْ إِلَى ٱلۡفِتۡنَةِ أُرۡكِسُواْ فِيهَاۚ فَإِن لَّمۡ يَعۡتَزِلُوكُمۡ وَيُلۡقُوٓاْ إِلَيۡكُمُ ٱلسَّلَمَ وَيَكُفُّوٓاْ أَيۡدِيَهُمۡ فَخُذُوهُمۡ وَٱقۡتُلُوهُمۡ حَيۡثُ ثَقِفۡتُمُوهُمۡۚ وَأُوْلَـٰٓئِكُمۡ جَعَلۡنَا لَكُمۡ عَلَيۡهِمۡ سُلۡطَٰنٗا مُّبِينٗا ٩١","ستجدون آخرين يريدون أن يأمنوكم ويأمنوا قومهم كل ما ردوا إلى الفتنة أركسوا فيها فإن لم يعتزلوكم ويلقوا إليكم السلم ويكفوا أيديهم فخذوهم واقتلوهم حيث ثقفتموهم وأولئكم جعلنا لكم عليهم سلطانا مبينا","ތިޔަބައިމީހުންގެ ކިބައިން އަމާން ކަން ލިބިގަތުމަށާއި، އެއުރެންގެ ގައުމުގެމީހުންގެ ކިބައިން އަމާން ކަން ލިބިގަތުމަށް އެދޭ އެހެންބަޔަކު ތިޔަބައިމީހުންނަށް ފެންނާނެތެވެ. އެއުރެން ފިތުނަވެރިކަމާއި، ޝިރުކުގެ ތެރެޔަށް އެނބުރިދިޔުމަށް ގޮވާލައިފި ކޮންމެ ހިނދެއްގައި އެއުރެން އެކަމުގެ ތެރެޔަށް ވެއްޓިގަނެއެވެ. ފަހެ އެއުރެން ތިޔަބައިމީހުންނާ އެއްކިބާ ނުވިނަމަ، އަދި، ތިޔަބައިމީހުންނަށް ތަސްލީމް ނުކުރިނަމަ، އަދި، އެއުރެންގެ އަތްތައް ހަނގުރާމައިން އެއްކިބާ ނުކުރިނަމަ، ދެން އެއުރެން ފެނުނު ކޮންމެތާކުން އަތުލައި ގަތުލުކުރާށެވެ! އަދި، ބަޔާން ވެގެންވާ ބާރުވެރިކަމެއް އެއުރެންގެ މައްޗަށް ތިޔަބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ.","",""],["₄ سورة النساء","92","وَمَا كَانَ لِمُؤۡمِنٍ أَن يَقۡتُلَ مُؤۡمِنًا إِلَّا خَطَـٔٗاۚ وَمَن قَتَلَ مُؤۡمِنًا خَطَـٔٗا فَتَحۡرِيرُ رَقَبَةٖ مُّؤۡمِنَةٖ وَدِيَةٞ مُّسَلَّمَةٌ إِلَىٰٓ أَهۡلِهِۦٓ إِلَّآ أَن يَصَّدَّقُواْۚ فَإِن كَانَ مِن قَوۡمٍ عَدُوّٖ لَّكُمۡ وَهُوَ مُؤۡمِنٞ فَتَحۡرِيرُ رَقَبَةٖ مُّؤۡمِنَةٖۖ وَإِن كَانَ مِن قَوۡمِۭ بَيۡنَكُمۡ وَبَيۡنَهُم مِّيثَٰقٞ فَدِيَةٞ مُّسَلَّمَةٌ إِلَىٰٓ أَهۡلِهِۦ وَتَحۡرِيرُ رَقَبَةٖ مُّؤۡمِنَةٖۖ فَمَن لَّمۡ يَجِدۡ فَصِيَامُ شَهۡرَيۡنِ مُتَتَابِعَيۡنِ تَوۡبَةٗ مِّنَ ٱللَّهِۗ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمٗا ٩٢","وما كان لمؤمن أن يقتل مؤمنا إلا خطأ ومن قتل مؤمنا خطأ فتحرير رقبة مؤمنة ودية مسلمة إلى أهله إلا أن يصدقوا فإن كان من قوم عدو لكم وهو مؤمن فتحرير رقبة مؤمنة وإن كان من قوم بينكم وبينهم ميثاق فدية مسلمة إلى أهله وتحرير رقبة مؤمنة فمن لم يجد فصيام شهرين متتابعين توبة من الله وكان الله عليما حكيما","ކުށަކުން، އޮޅިގެންމެނުވީ މުއުމިނަކު މެރުމަކީ، މުއުމިނަކަށް އޮތްކަމެއްނޫނެވެ. އަދި، ކުށަކުން އޮޅިގެން މުއުމިނަކު މަރައިފިމީހާ (ދަންނާށެވެ!) ފަހެ، އޭނާއަށްހުރީ، މުއުމިނު އަޅަކު މިނިވަންކުރުމާއި، އެ މަރުވިމީހާގެ އަހުލުވެރިންނާ ޙަވާލުކުރެވޭގޮތުގައި، މަރުގެދިޔަ ދިނުމެވެ. އެއީ، އެއުރެން (މާފުކުރުމަކުން) އެއިން ސަދަގާތްކުރިއްޔާ މެނުވީއެވެ. އަދި، މަރުވި މީހާއީ މުއުމިނަކުކަމުގައި ވުމާއެކު، ތިޔަބައިމީހުންނާ އަދާވަތް ތެރި ގައުމެއްގެ މީހަކު ކަމުގައިވާނަމަ ފަހެ، މުއުމިނު އަޅަކު މިނިވަންކުރުން ހުށްޓެވެ. އަދި، އެބަޔަކާ ތިޔަބައިމީހުންނާ ދެމެދުގައި އަހުދެއް ކުރެވިފައިވާ ބަޔެއްގެ ތެރެއިންވާ މީހަކުނަމަ، ފަހެ، އެމީހެއްގެ އަހުލުވެރިންނާ ޙަވާލުކުރެވޭގޮތުގައި މަރުގެދިޔަ ދިނުމާއި، މުއުމިނު އަޅަކު މިނިވަންކުރުން ހުށްޓެވެ. ފަހެ، (މިނިވަންކުރާނެ އަޅަކު) ނުލިބުނުމީހާ ފަހެ، ވިދިވިދިގެން ދެމަސްދުވަހު ރޯދަހިފުން ހުށްޓެވެ. (އެއީ) ﷲގެ ހަޒުރަތުން ތައުބާ ލިބިގަތުމެއްގެ ގޮތުގައެވެ. މޮޅަށް ދެނެވޮޑިގެންވާ ޙަކީމްވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","93","وَمَن يَقۡتُلۡ مُؤۡمِنٗا مُّتَعَمِّدٗا فَجَزَآؤُهُۥ جَهَنَّمُ خَٰلِدٗا فِيهَا وَغَضِبَ ٱللَّهُ عَلَيۡهِ وَلَعَنَهُۥ وَأَعَدَّ لَهُۥ عَذَابًا عَظِيمٗا ٩٣","ومن يقتل مؤمنا متعمدا فجزاؤه جهنم خالدا فيها وغضب الله عليه ولعنه وأعد له عذابا عظيما","އަދި، ގަސްދުގައި މުއުމިނަކު މަރާމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާގެ ޖަޒާއަކީ ނަރަކަޔެވެ. އެތާނގައި ދެމިހުންނަނިވި ގޮތުގައެވެ. އަދި، ﷲ، އެމީހާގެ މައްޗަށް ކޯފާލައްވައި ލައުނަތް ލެއްވިއެވެ. އަދި، ބޮޑުވެގެންވާ އަޒާބު އެމީހާއަށް ތައްޔާރު ކުރެއްވިއެވެ.","",""],["₄ سورة النساء","94","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ إِذَا ضَرَبۡتُمۡ فِي سَبِيلِ ٱللَّهِ فَتَبَيَّنُواْ وَلَا تَقُولُواْ لِمَنۡ أَلۡقَىٰٓ إِلَيۡكُمُ ٱلسَّلَٰمَ لَسۡتَ مُؤۡمِنٗا تَبۡتَغُونَ عَرَضَ ٱلۡحَيَوٰةِ ٱلدُّنۡيَا فَعِندَ ٱللَّهِ مَغَانِمُ كَثِيرَةٞۚ كَذَٰلِكَ كُنتُم مِّن قَبۡلُ فَمَنَّ ٱللَّهُ عَلَيۡكُمۡ فَتَبَيَّنُوٓاْۚ إِنَّ ٱللَّهَ كَانَ بِمَا تَعۡمَلُونَ خَبِيرٗا ٩٤","يا أيها الذين آمنوا إذا ضربتم في سبيل الله فتبينوا ولا تقولوا لمن ألقى إليكم السلام لست مؤمنا تبتغون عرض الحياة الدنيا فعند الله مغانم كثيرة كذلك كنتم من قبل فمن الله عليكم فتبينوا إن الله كان بما تعملون خبيرا","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ﷲގެ މަގުގައި ދަތުރުފަތުރުކޮށް އުޅޭހިނދު، ފަހެ (ކަންކަމުގެ) ހަގީގަތް ބަލައި އޮޅުންފިލުވާށެވެ! އަދި، ދުނިޔޭގެ ދިރިއުޅުމުގައި ލިބޭ ފައިދާއާއި، މުދަލަށް ތިޔަބައިމީހުން އެދޭ ޙާލުގައި (އިސްލާމް ދީންގެ ސަލާމުން) ތިޔަބައިމީހުންނަށް ސަލާމް ކޮށްފިމީހަކަށް ތިބާއަކީ މުއުމިނެއް ނޫނޭ ތިޔަބައިމީހުން ނުބުނާހުށިކަމެވެ! ފަހެ، ގިނަވެގެންވާ ފައިދާތައް ވަނީ ﷲގެ ހަޒުރަތު ގައެވެ. ތިޔަބައިމީހުން މީގެކުރިން ތިބިފަދައިންނެވެ. ދެން ﷲ، ތިޔަބައިމީހުންގެ މައްޗަށް ދަރުމަވަންތަވެ ވޮޑިގަތެވެ. ފަހެ، ތިޔަބައިމީހުން (ކަންކަމުގެ) ހަގީގަތް ބަލައި އޮޅުންފިލުވާށެވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ކުރާ ޢަމަލުތައް މޮޅަށް ދެނެވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","95","لَّا يَسۡتَوِي ٱلۡقَٰعِدُونَ مِنَ ٱلۡمُؤۡمِنِينَ غَيۡرُ أُوْلِي ٱلضَّرَرِ وَٱلۡمُجَٰهِدُونَ فِي سَبِيلِ ٱللَّهِ بِأَمۡوَٰلِهِمۡ وَأَنفُسِهِمۡۚ فَضَّلَ ٱللَّهُ ٱلۡمُجَٰهِدِينَ بِأَمۡوَٰلِهِمۡ وَأَنفُسِهِمۡ عَلَى ٱلۡقَٰعِدِينَ دَرَجَةٗۚ وَكُلّٗا وَعَدَ ٱللَّهُ ٱلۡحُسۡنَىٰۚ وَفَضَّلَ ٱللَّهُ ٱلۡمُجَٰهِدِينَ عَلَى ٱلۡقَٰعِدِينَ أَجۡرًا عَظِيمٗا ٩٥","لا يستوي القاعدون من المؤمنين غير أولي الضرر والمجاهدون في سبيل الله بأموالهم وأنفسهم فضل الله المجاهدين بأموالهم وأنفسهم على القاعدين درجة وكلا وعد الله الحسنى وفضل الله المجاهدين على القاعدين أجرا عظيما","މުއުމިނުންގެ ތެރެއިން (ޖިހާދު ނުކުރެވޭފަދަ) އުޒުރުތަކުގެ ވެރިން ފިޔަވައި، ހަނގުރާމަޔަށް ނުގޮސްތިބޭ މީހުން ﷲގެ މަގުގައި އެއުރެންގެ މުދާތަކާއި، ނަފްސު ތަކުން ޖިހާދުކުރާ މީހުންނާ ހަމަހަމަ ވެގެނެއްނުވެތެވެ. އެއުރެންގެ މުދާތަކާއި، ނަފްސު ތަކުން ޖިހާދުކުރާ މީހުން، ހަނގުރާމަޔަށް ނުގޮސްތިބޭ މީހުންނަށްވުރެން ދަރަޖައިގެގޮތުން ﷲ މާތްކުރައްވާފައިވެއެވެ. އެއިން ކޮންމެ ބަޔަކަށްމެ، ހެޔޮދަރުމަ ދެއްވުމަށް ﷲ ވައުދު ވެވޮޑިގެންފައިވެއެވެ. ހަނގުރާމަޔަށް ނުގޮސްތިބޭ މީހުންނަށްވުރެން ޖިހާދުކުރާ މީހުން ބޮޑުވެގެންވާ ދަރުމަ ދެއްވުމަށް ﷲ މާތްކުރެއްވިއެވެ.","",""],["₄ سورة النساء","96","دَرَجَٰتٖ مِّنۡهُ وَمَغۡفِرَةٗ وَرَحۡمَةٗۚ وَكَانَ ٱللَّهُ غَفُورٗا رَّحِيمًا ٩٦","درجات منه ومغفرة ورحمة وكان الله غفورا رحيما","(އެއީ) އެކަލާނގެ ހަޒުރަތުން ލިބޭ ދަރަޖަތަކެކެވެ. އަދި، ފާފަ ފުއްސެވުމެކެވެ. އަދި، ރަހުމަތެކެވެ. އަދި، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","97","إِنَّ ٱلَّذِينَ تَوَفَّىٰهُمُ ٱلۡمَلَـٰٓئِكَةُ ظَالِمِيٓ أَنفُسِهِمۡ قَالُواْ فِيمَ كُنتُمۡۖ قَالُواْ كُنَّا مُسۡتَضۡعَفِينَ فِي ٱلۡأَرۡضِۚ قَالُوٓاْ أَلَمۡ تَكُنۡ أَرۡضُ ٱللَّهِ وَٰسِعَةٗ فَتُهَاجِرُواْ فِيهَاۚ فَأُوْلَـٰٓئِكَ مَأۡوَىٰهُمۡ جَهَنَّمُۖ وَسَآءَتۡ مَصِيرًا ٩٧","إن الذين توفاهم الملائكة ظالمي أنفسهم قالوا فيم كنتم قالوا كنا مستضعفين في الأرض قالوا ألم تكن أرض الله واسعة فتهاجروا فيها فأولئك مأواهم جهنم وساءت مصيرا","ހަމަކަށަވަރުން އެއުރެންގެ ނަފްސުތަކަށް އަނިޔާވެރިވެގެން ތިބޭ ޙާލުގައި، މަލާއިކަތުން، އެއުރެންގެ މަރު ހިއްޕަވާ މީހުންނަށް ވިދާޅުވާނެތެވެ. ތިޔަބައިމީހުން އުޅުނީ ކޮންގޮތެއްގައިހޭ؟ އެއުރެން ދަންނަވާނެތެވެ. ތިމަންމެންވީ، ބިމުގައި ނިކަމެތިކަން ލިބިގެންވީ ބަޔަކު ކަމުގައެވެ. އެބޭކަލުން ވިދާޅުވާނެތެވެ. ތިޔަބައިމީހުން، އެ ބިމުގައި ހިޖުރަކުރުމަށް ﷲގެ ބިން ތަނަވަސްވެގެންނުވޭހޭ؟ ފަހެ (ގިޔާމަތް ދުވަހުން) އެއުރެން ތިބެނިވި ތަނަކީ ނަރަކަޔެވެ. އެއީ، ނުބައިވެގެންވާ ނިމިދިޔުމެކެވެ.","",""],["₄ سورة النساء","98","إِلَّا ٱلۡمُسۡتَضۡعَفِينَ مِنَ ٱلرِّجَالِ وَٱلنِّسَآءِ وَٱلۡوِلۡدَٰنِ لَا يَسۡتَطِيعُونَ حِيلَةٗ وَلَا يَهۡتَدُونَ سَبِيلٗا ٩٨","إلا المستضعفين من الرجال والنساء والولدان لا يستطيعون حيلة ولا يهتدون سبيلا","(ހިޖުރަކުރާނެ) ގޮތެއްގެ ކުޅަދާނަކަން ލިބިގެންނުވާ، އަދި، (ހިޖުރަ ޔަށް) ދާނެމަގެއް ފެނިފައިނުވާ ނިކަމެތި ފިރިހެނުންނާއި، އަންހެނުންނާއި، ކުޑަކުދިން މެނުވީއެވެ.","",""],["₄ سورة النساء","99","فَأُوْلَـٰٓئِكَ عَسَى ٱللَّهُ أَن يَعۡفُوَ عَنۡهُمۡۚ وَكَانَ ٱللَّهُ عَفُوًّا غَفُورٗا ٩٩","فأولئك عسى الله أن يعفو عنهم وكان الله عفوا غفورا","އެއުރެންގެ ކިބައިން ﷲ، އަފޫކުރެއްވުން ގާތްވެގެންވެއެވެ. ގިނަގިނައިން އަފޫކުރައްވާ، ގިނަގިނައިން ފާފަފުއްސަވާ ކަލަކުކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","100","۞وَمَن يُهَاجِرۡ فِي سَبِيلِ ٱللَّهِ يَجِدۡ فِي ٱلۡأَرۡضِ مُرَٰغَمٗا كَثِيرٗا وَسَعَةٗۚ وَمَن يَخۡرُجۡ مِنۢ بَيۡتِهِۦ مُهَاجِرًا إِلَى ٱللَّهِ وَرَسُولِهِۦ ثُمَّ يُدۡرِكۡهُ ٱلۡمَوۡتُ فَقَدۡ وَقَعَ أَجۡرُهُۥ عَلَى ٱللَّهِۗ وَكَانَ ٱللَّهُ غَفُورٗا رَّحِيمٗا ١٠٠","ومن يهاجر في سبيل الله يجد في الأرض مراغما كثيرا وسعة ومن يخرج من بيته مهاجرا إلى الله ورسوله ثم يدركه الموت فقد وقع أجره على الله وكان الله غفورا رحيما","ﷲގެ މަގުގައި ހިޖުރަކުރާ މީހަކަށް، ބިމުގައި ހިޖުރަ ކޮށްއުޅޭނެ ގިނަތަންތަނާއި، ތަނަވަސްކަން ފެންނާނެތެވެ. އަދި، ﷲއާއި، އެކަލާނގެ ރަސޫލާއަށްޓަކައި ހިޖުރަކުރާ ޙާލު، އެމީހެއްގެ ގެއިން ނުކުންނަމީހާ، ދެން މަރުއައިސް އެމީހަކު އަތުލާމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އެމީހެއްގެ ދަރުމަ ﷲގެ ހަޒުރަތުގައި ޘާބިތު ވެއްޖެއެވެ. ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","101","وَإِذَا ضَرَبۡتُمۡ فِي ٱلۡأَرۡضِ فَلَيۡسَ عَلَيۡكُمۡ جُنَاحٌ أَن تَقۡصُرُواْ مِنَ ٱلصَّلَوٰةِ إِنۡ خِفۡتُمۡ أَن يَفۡتِنَكُمُ ٱلَّذِينَ كَفَرُوٓاْۚ إِنَّ ٱلۡكَٰفِرِينَ كَانُواْ لَكُمۡ عَدُوّٗا مُّبِينٗا ١٠١","وإذا ضربتم في الأرض فليس عليكم جناح أن تقصروا من الصلاة إن خفتم أن يفتنكم الذين كفروا إن الكافرين كانوا لكم عدوا مبينا","ތިޔަބައިމީހުން ބިމުގައި ދަތުރުފަތުރުކޮށް އުޅޭއިރު، ކާފިރުވި މީހުން ތިޔަބައިމީހުންނަށް ގެއްލުމެއް ދީފާނެކަމަށް ބިރުގެންފިނަމަ، ނަމާދު ގަޞްރުކުރުމަކުން ތިޔަބައިމީހުންގެ މައްޗަކަށް ކުށެއްނެތެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށް ފާޅުވެގެންވާ އަދާވަތް ތެރިން ކަމުގައި ކާފިރުން ވިއެވެ.","",""],["₄ سورة النساء","102","وَإِذَا كُنتَ فِيهِمۡ فَأَقَمۡتَ لَهُمُ ٱلصَّلَوٰةَ فَلۡتَقُمۡ طَآئِفَةٞ مِّنۡهُم مَّعَكَ وَلۡيَأۡخُذُوٓاْ أَسۡلِحَتَهُمۡۖ فَإِذَا سَجَدُواْ فَلۡيَكُونُواْ مِن وَرَآئِكُمۡ وَلۡتَأۡتِ طَآئِفَةٌ أُخۡرَىٰ لَمۡ يُصَلُّواْ فَلۡيُصَلُّواْ مَعَكَ وَلۡيَأۡخُذُواْ حِذۡرَهُمۡ وَأَسۡلِحَتَهُمۡۗ وَدَّ ٱلَّذِينَ كَفَرُواْ لَوۡ تَغۡفُلُونَ عَنۡ أَسۡلِحَتِكُمۡ وَأَمۡتِعَتِكُمۡ فَيَمِيلُونَ عَلَيۡكُم مَّيۡلَةٗ وَٰحِدَةٗۚ وَلَا جُنَاحَ عَلَيۡكُمۡ إِن كَانَ بِكُمۡ أَذٗى مِّن مَّطَرٍ أَوۡ كُنتُم مَّرۡضَىٰٓ أَن تَضَعُوٓاْ أَسۡلِحَتَكُمۡۖ وَخُذُواْ حِذۡرَكُمۡۗ إِنَّ ٱللَّهَ أَعَدَّ لِلۡكَٰفِرِينَ عَذَابٗا مُّهِينٗا ١٠٢","وإذا كنت فيهم فأقمت لهم الصلاة فلتقم طائفة منهم معك وليأخذوا أسلحتهم فإذا سجدوا فليكونوا من ورائكم ولتأت طائفة أخرى لم يصلوا فليصلوا معك وليأخذوا حذرهم وأسلحتهم ود الذين كفروا لو تغفلون عن أسلحتكم وأمتعتكم فيميلون عليكم ميلة واحدة ولا جناح عليكم إن كان بكم أذى من مطر أو كنتم مرضى أن تضعوا أسلحتكم وخذوا حذركم إن الله أعد للكافرين عذابا مهينا","އަދި، އެއުރެންގެ ތެރޭގައި ކަލޭގެފާނު ހުންނަވައި އެއުރެންނާއިގެން ނަމާދު ގާއިމުކުރައްވައިފިނަމަ، އެއުރެންގެ ތެރެއިން ބަޔަކު ކަލޭގެފާނާއެކުގައި ނަމާދަށް ގާއިމު ވާހުށިކަމެވެ! އަދި، އެއުރެންގެ ހަތިޔާރުތައް އެއުރެން ހިފާހުށިކަމެވެ! (އެބަހީ: ހަތިޔާރު އަޅައިގެންތިބެ ނަމާދުކުރާ ހުށިކަމެވެ!) ދެން، އެއުރެން ސަޖިދަ ކޮށްފިނަމަ (އެބަހީ: ފުރަތަމަ ރަކުޢަތް ފުރިހަމަކޮށްފުމަށް ދާނދެން) ނަމާދު ނުކޮށް ފާރަޔަށް ތިބިމީހުން އެއުރެންގެ ފަހަތުގައި ތިބޭހުށިކަމެވެ! އަދި، ނަމާދު ނުކޮށް ތިބިމީހުން އައިސް، ކަލޭގެފާނާއެކުގައި ނަމާދުކުރާ ހުށިކަމެވެ! އަދި، އެއުރެން ހަތިޔާރުތަކާއި، ރައްކާތެރިކަމުގައި ހިފާހުށިކަމެވެ! ތިޔަބައިމީހުން ގެންގުޅޭ ތަކެއްޗާއި، ހަތިޔާރުތަކާމެދު، ތިޔަބައިމީހުން ޣާފިލު ވާނެނަމައޭ ހިތައި، ކާފިރުވި މީހުން (އެކަމަށް) އެދުނެވެ. އޭރުން، އެއްފަހަރާ ލެނބިގަންނަ ލެނބިގަތުމަކުން ތިޔަބައިމީހުންގެ މައްޗަށް އެއުރެން ލެނބިގެންފާނެތެވެ. (އެބަހީ: އެއްފަހަރާ އައިސް ހަމަލާ ދީފާނެތެވެ.) ވާރެއިން ތިޔަބައިމީހުންނަށް އުނދަގުލެއް ލިބިފައިވާނަމަ، ނުވަތަ، ތިޔަބައިމީހުން ބަލިވެއުޅޭ ބަޔަކު ކަމުގައިވާނަމަ، ތިޔަބައިމީހުންގެ ހަތިޔާރުތައް (ނާޅައި) ބެހެއްޓުމަކުން ތިޔަބައިމީހުންގެ މައްޗަކަށް ކުށެއްނެތެވެ. އަދި، ތިޔަބައިމީހުން ރައްކާތެރިކަމުގައި ހިފާށެވެ! ހަމަކަށަވަރުން، ކާފިރުންނަށް، އިހާނަތް ތެރި އަޒާބު، ﷲތައްޔާރުކުރެއްވިއެވެ.","",""],["₄ سورة النساء","103","فَإِذَا قَضَيۡتُمُ ٱلصَّلَوٰةَ فَٱذۡكُرُواْ ٱللَّهَ قِيَٰمٗا وَقُعُودٗا وَعَلَىٰ جُنُوبِكُمۡۚ فَإِذَا ٱطۡمَأۡنَنتُمۡ فَأَقِيمُواْ ٱلصَّلَوٰةَۚ إِنَّ ٱلصَّلَوٰةَ كَانَتۡ عَلَى ٱلۡمُؤۡمِنِينَ كِتَٰبٗا مَّوۡقُوتٗا ١٠٣","فإذا قضيتم الصلاة فاذكروا الله قياما وقعودا وعلى جنوبكم فإذا اطمأننتم فأقيموا الصلاة إن الصلاة كانت على المؤمنين كتابا موقوتا","އަދި، ތިޔަބައިމީހުން ނަމާދުކޮށް އަވަދިވެއްޖިއްޔާ، ތިޔަބައިމީހުން ﷲ ހަނދުމަކޮށް އުޅޭށެވެ! ކޮޅަށްތިބޭ ޙާލު ގައްޔާއި، އިށީނދެތިބޭ ޙާލު ގައްޔާއި، އޮށޯވެތިބޭ ޙާލު ގައެވެ. އަދި، ތިޔަބައިމީހުންނަށް އަމާން ކަން ލިބިއްޖެ ހިނދަކު، ނަމާދު (ފުރިހަމަކޮށް) ގާއިމުކުރާށެވެ! ހަމަކަށަވަރުން، ނަމާދަކީ މުއުމިނު ތަކުންގެ މައްޗަށް ވަގުތު ކަނޑައެޅިގެންއޮތް ފަރުޟެއްކަމުގައި ވެއެވެ.","",""],["₄ سورة النساء","104","وَلَا تَهِنُواْ فِي ٱبۡتِغَآءِ ٱلۡقَوۡمِۖ إِن تَكُونُواْ تَأۡلَمُونَ فَإِنَّهُمۡ يَأۡلَمُونَ كَمَا تَأۡلَمُونَۖ وَتَرۡجُونَ مِنَ ٱللَّهِ مَا لَا يَرۡجُونَۗ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمًا ١٠٤","ولا تهنوا في ابتغاء القوم إن تكونوا تألمون فإنهم يألمون كما تألمون وترجون من الله ما لا يرجون وكان الله عليما حكيما","ތިޔަބައިމީހުން ދުޝްމަނުން އަތުލައިގަތުމުގައި ފިނޑިވެ ނިކަމެތިނުވާހުށިކަމެވެ! ތިޔަބައިމީހުންނަށް (ލިބިފައިވާ ހާނީއްކައިގެ ސަބަބުން) ވޭންލިބޭ ކަމުގައިވާނަމަ، ފަހެ، ތިޔަބައިމީހުންނަށް ވޭންލިބޭފަދައިން، ހަމަކަށަވަރުން، އެއުރެންނަށްވެސް ވޭންލިބޭނެތެވެ. އެއުރެން ނޭދޭކަންތައް ﷲގެ ހަޒުރަތުން ތިޔަބައިމީހުން އެދެމުއެވެ. މޮޅަށް ދެނެވޮޑިގެންވާ ޙަކީމްވަންތަ ކަލަކުކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","105","إِنَّآ أَنزَلۡنَآ إِلَيۡكَ ٱلۡكِتَٰبَ بِٱلۡحَقِّ لِتَحۡكُمَ بَيۡنَ ٱلنَّاسِ بِمَآ أَرَىٰكَ ٱللَّهُۚ وَلَا تَكُن لِّلۡخَآئِنِينَ خَصِيمٗا ١٠٥","إنا أنزلنا إليك الكتاب بالحق لتحكم بين الناس بما أراك الله ولا تكن للخائنين خصيما","ހަމަކަށަވަރުން، ހައްގު ގޮތުގައި ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ފޮތް ބާވައިލެއްވީ، ކަލޭގެފާނަށް ﷲ އަންގަވާފައިވާ ގޮތުގެމަތިން، މީސްތަކުންގެ މެދުގައި ހުކުމްކުރެއްވުމަށެވެ. ޚިޔާނަތް ތެރިންގެ ދިފާޢުގައި މަސައްކަތް ކުރައްވާ ބޭކަލަކުކަމުގައި ކަލޭގެފާނު ވެވަޑައި ނުގަންނަވާށެވެ!","",""],["₄ سورة النساء","106","وَٱسۡتَغۡفِرِ ٱللَّهَۖ إِنَّ ٱللَّهَ كَانَ غَفُورٗا رَّحِيمٗا ١٠٦","واستغفر الله إن الله كان غفورا رحيما","އަދި، ފާފަފުއްސެވުން އެދި، ﷲގެ ހަޒުރަތަށް ކަލޭގެފާނު ދަންނަވާށެވެ! ހަމަކަށަވަރުން، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","107","وَلَا تُجَٰدِلۡ عَنِ ٱلَّذِينَ يَخۡتَانُونَ أَنفُسَهُمۡۚ إِنَّ ٱللَّهَ لَا يُحِبُّ مَن كَانَ خَوَّانًا أَثِيمٗا ١٠٧","ولا تجادل عن الذين يختانون أنفسهم إن الله لا يحب من كان خوانا أثيما","އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް ޚިޔާނަތް ތެރިވާ މީހުންގެ ފަރާތުން، ކަލޭގެފާނު ޖަދަލު ނުކުރައްވާށެވެ! ހަމަކަށަވަރުން، ފާފަވެރިވެ ޚިޔާނަތް ތެރިވާ މީހަކު ދެކެ ﷲ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["₄ سورة النساء","108","يَسۡتَخۡفُونَ مِنَ ٱلنَّاسِ وَلَا يَسۡتَخۡفُونَ مِنَ ٱللَّهِ وَهُوَ مَعَهُمۡ إِذۡ يُبَيِّتُونَ مَا لَا يَرۡضَىٰ مِنَ ٱلۡقَوۡلِۚ وَكَانَ ٱللَّهُ بِمَا يَعۡمَلُونَ مُحِيطًا ١٠٨","يستخفون من الناس ولا يستخفون من الله وهو معهم إذ يبيتون ما لا يرضى من القول وكان الله بما يعملون محيطا","އެއުރެން މީސްތަކުންނަށް ވަންހަނާވެގަނެތެވެ. އެކަމަކު، ﷲގެ ހަޒުރަތަށް އެއުރެންނަކަށް ވަންހަނާވެއެއް ނުގަނެވެތެވެ. އެކަލާނގެ ރުހިވޮޑިގެންނުވާ ބަސްތައް، އެއުރެން ވަންހަނާގައި ތަދްބީރު ކޮށް އުޅޭހިނދު، އެއުރެންނާ އެކުގައި އެކަލާނގެ ވޮޑިގެންވެއެވެ. އެއުރެން ކުރާ ޢަމަލުތައް، ފުރިހަމަޔަށް ދެނެވޮޑިގެންވާ ކަލަކުކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","109","هَـٰٓأَنتُمۡ هَـٰٓؤُلَآءِ جَٰدَلۡتُمۡ عَنۡهُمۡ فِي ٱلۡحَيَوٰةِ ٱلدُّنۡيَا فَمَن يُجَٰدِلُ ٱللَّهَ عَنۡهُمۡ يَوۡمَ ٱلۡقِيَٰمَةِ أَم مَّن يَكُونُ عَلَيۡهِمۡ وَكِيلٗا ١٠٩","ها أنتم هؤلاء جادلتم عنهم في الحياة الدنيا فمن يجادل الله عنهم يوم القيامة أم من يكون عليهم وكيلا","ދުނިޔޭގެ ހަޔާތުގައި އެއުރެންގެ ފަރާތުން، ތިޔަބައިމީހުން ތިޔަ ޖަދަލު ކުރީއެވެ. ގިޔާމަތް ދުވަހުން އެއުރެންގެ ފަރާތުން ﷲއާ ޖަދަލުކުރާނީ ފަހެ ކާކުހެއްޔެވެ؟ ނުވަތަ، އެއުރެންގެ ކަންތަކާ ޙަވާލުވެ ދިފާޢުކުރާނޭ ވަކީލަކަށްވާނީ ފަހެ ކާކުހެއްޔެވެ؟","",""],["₄ سورة النساء","110","وَمَن يَعۡمَلۡ سُوٓءًا أَوۡ يَظۡلِمۡ نَفۡسَهُۥ ثُمَّ يَسۡتَغۡفِرِ ٱللَّهَ يَجِدِ ٱللَّهَ غَفُورٗا رَّحِيمٗا ١١٠","ومن يعمل سوءا أو يظلم نفسه ثم يستغفر الله يجد الله غفورا رحيما","ނުބައިކަމެއްކޮށް، ނުވަތަ، އެމީހެއްގެ އަމިއްލަ ނަފްސަށް އަނިޔާވެރިވެ، ދެން (އެއަށްފަހު) ފާފަފުއްސެވުން އެދި ﷲގެ ހަޒުރަތަށް ދަންނަވާމީހާ (ދަންނާށެވެ!) ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ކަލަކު ކަމުގައި އޭނާ ދެކޭނެއެވެ.","",""],["₄ سورة النساء","111","وَمَن يَكۡسِبۡ إِثۡمٗا فَإِنَّمَا يَكۡسِبُهُۥ عَلَىٰ نَفۡسِهِۦۚ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمٗا ١١١","ومن يكسب إثما فإنما يكسبه على نفسه وكان الله عليما حكيما","އަދި، ފާފައެއް ލިބިގަންނަމީހާ، އެކަން އެ ލިބިގަންނަނީ، ހަމަ އެމީހާގެ އަމިއްލަ ނަފްސުގެ މައްޗަށްކަން ކަށަވަރެވެ. މޮޅަށް ދެނެވޮޑިގެންވާ ޙަކީމްވަންތަ ކަލަކުކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","112","وَمَن يَكۡسِبۡ خَطِيٓـَٔةً أَوۡ إِثۡمٗا ثُمَّ يَرۡمِ بِهِۦ بَرِيٓـٔٗا فَقَدِ ٱحۡتَمَلَ بُهۡتَٰنٗا وَإِثۡمٗا مُّبِينٗا ١١٢","ومن يكسب خطيئة أو إثما ثم يرم به بريئا فقد احتمل بهتانا وإثما مبينا","އަދި، ކުށެއް ނުވަތަ ފާފައެއްކޮށް (އެކަމުގެ) ކުށެއްނެތް މީހެއްގައި އެކަން އަޅުވާމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާ ބޮޑުވެގެންވާ ދޮގަކާއި، ފާޅުވެގެންވާ ފާފައެއް އުފުލައިފިކަން ކަށަވަރެވެ.","",""],["₄ سورة النساء","113","وَلَوۡلَا فَضۡلُ ٱللَّهِ عَلَيۡكَ وَرَحۡمَتُهُۥ لَهَمَّت طَّآئِفَةٞ مِّنۡهُمۡ أَن يُضِلُّوكَ وَمَا يُضِلُّونَ إِلَّآ أَنفُسَهُمۡۖ وَمَا يَضُرُّونَكَ مِن شَيۡءٖۚ وَأَنزَلَ ٱللَّهُ عَلَيۡكَ ٱلۡكِتَٰبَ وَٱلۡحِكۡمَةَ وَعَلَّمَكَ مَا لَمۡ تَكُن تَعۡلَمُۚ وَكَانَ فَضۡلُ ٱللَّهِ عَلَيۡكَ عَظِيمٗا ١١٣","ولولا فضل الله عليك ورحمته لهمت طائفة منهم أن يضلوك وما يضلون إلا أنفسهم وما يضرونك من شيء وأنزل الله عليك الكتاب والحكمة وعلمك ما لم تكن تعلم وكان فضل الله عليك عظيما","ކަލޭގެފާނުގެ މައްޗަށް ﷲގެ ފަޟްލު ވަންތަކަމާއި، އެކަލާނގެ ރަހުމަތް ނުވާނަމަ، ކަލޭގެފާނަށް އޮޅުވައިލުމަށް އެއުރެންގެ ތެރެއިން ބަޔަކު އުޅެފީހެވެ. ނަމަވެސް އެއުރެންގެ އަމިއްލަ ނަފްސު ތަކަށްމެނުވީ، އެއުރެންނަށް އޮޅުވަޔެއް ނުލެވެތެވެ. އަދި، އެއްވެސް ކަމަކުން އެއުރެންނަށް ކަލޭގެފާނަކަށް ގެއްލުމެއް ނުދެވޭނެތެވެ. ކަލޭގެފާނަށް ﷲ، ހިކުމަތާއި، ފޮތް ބާވައިލައްވާފައި ވެއެވެ. އަދި، ކަލޭގެފާނު އިހަށް ދެނެވަޑައިނުގަންނަވާ ކަންތައް ކަލޭގެފާނަށް އެކަލާނގެ އުނގަންނައި ދެއްވިއެވެ. އަދި، ކަލޭގެފާނުގެ މައްޗަށް ﷲގެ ފަޟްލު ވަންތަކަން ބޮޑުވެގެންވެއެވެ.","",""],["₄ سورة النساء","114","۞لَّا خَيۡرَ فِي كَثِيرٖ مِّن نَّجۡوَىٰهُمۡ إِلَّا مَنۡ أَمَرَ بِصَدَقَةٍ أَوۡ مَعۡرُوفٍ أَوۡ إِصۡلَٰحِۭ بَيۡنَ ٱلنَّاسِۚ وَمَن يَفۡعَلۡ ذَٰلِكَ ٱبۡتِغَآءَ مَرۡضَاتِ ٱللَّهِ فَسَوۡفَ نُؤۡتِيهِ أَجۡرًا عَظِيمٗا ١١٤","لا خير في كثير من نجواهم إلا من أمر بصدقة أو معروف أو إصلاح بين الناس ومن يفعل ذلك ابتغاء مرضات الله فسوف نؤتيه أجرا عظيما","ސަދަގާތެއްކުރުމަށް، ނުވަތަ ހެޔޮކަމެއް ކުރުމަށް، ނުވަތަ މީސްތަކުންގެ މެދުގައި ޞުލްޙެއް އުފެއްދުމަށް އަމުރު ކޮށްފި މީހަކު (ސިއްރުގޮތުގައި ދައްކާ ވާހަކަ) މެނުވީ، އެއުރެން ސިއްރުގޮތުގައި ދައްކާ ގިނަ ވާހަކަތަކުގައި ހެޔޮކަމެއް ނެތެވެ. އަދި، ﷲ ރުހިވޮޑިގަތުން އެދިގެން އެކަންތައް ކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، ތިމަންރަސްކަލާނގެ އެމީހަކަށް ބޮޑުވެގެންވާ ދަރުމައެއް ދެއްވާހުށީމެވެ.","",""],["₄ سورة النساء","115","وَمَن يُشَاقِقِ ٱلرَّسُولَ مِنۢ بَعۡدِ مَا تَبَيَّنَ لَهُ ٱلۡهُدَىٰ وَيَتَّبِعۡ غَيۡرَ سَبِيلِ ٱلۡمُؤۡمِنِينَ نُوَلِّهِۦ مَا تَوَلَّىٰ وَنُصۡلِهِۦ جَهَنَّمَۖ وَسَآءَتۡ مَصِيرًا ١١٥","ومن يشاقق الرسول من بعد ما تبين له الهدى ويتبع غير سبيل المؤمنين نوله ما تولى ونصله جهنم وساءت مصيرا","އަދި، އެމީހަކަށް ތެދުމަގު ބަޔާން ވުމަށްފަހު، ރަސޫލާއާ ދެކޮޅުވެރިވެ، މުއުމިނުންގެ މަގު ނޫން މަގަކަށް ތަބާ ވާމީހާ (ދަންނާށެވެ!) އެމީހާ އިޚްތިޔާރުކުރި މަގަކަށް ތިމަންރަސްކަލާނގެ އެމީހާ ދޫކޮށްލައްވާ ހުށީމެވެ. އަދި، ތިމަންރަސްކަލާނގެ އެމީހާ ނަރަކަޔަށް ވައްދަވާ ހުށީމެވެ. އެއީ، ނުބައިވެގެންވާ ނިމިދިޔުމެކެވެ.","",""],["₄ سورة النساء","116","إِنَّ ٱللَّهَ لَا يَغۡفِرُ أَن يُشۡرَكَ بِهِۦ وَيَغۡفِرُ مَا دُونَ ذَٰلِكَ لِمَن يَشَآءُۚ وَمَن يُشۡرِكۡ بِٱللَّهِ فَقَدۡ ضَلَّ ضَلَٰلَۢا بَعِيدًا ١١٦","إن الله لا يغفر أن يشرك به ويغفر ما دون ذلك لمن يشاء ومن يشرك بالله فقد ضل ضلالا بعيدا","ހަމަކަށަވަރުން، ﷲ، އެކަލާނގެއަށް ޝަރީކުކުރުމުގެ ފާފައެއް ނުފުއްސަވާނެތެވެ. އެނޫން ފާފަތައް، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ފުއްސަވަތެވެ. ﷲއަށް ޝަރީކުކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، އޭނާ ދުރުވެގެންވާ މަގުފުރެދުމަކުން މަގުފުރެދިއްޖެކަން ކަށަވަރެވެ.","",""],["₄ سورة النساء","117","إِن يَدۡعُونَ مِن دُونِهِۦٓ إِلَّآ إِنَٰثٗا وَإِن يَدۡعُونَ إِلَّا شَيۡطَٰنٗا مَّرِيدٗا ١١٧","إن يدعون من دونه إلا إناثا وإن يدعون إلا شيطانا مريدا","އެކަލާނގެ ފިޔަވައި އަންހެން (ނަންތަކެއް ކިއިގެންވާ) ބުދުތަކަކަށް މެނުވީ، އެއުރެން އަޅުކަމެއް ނުކުރެތެވެ. އަދި، ނުބައިކަމާއި ނުކިޔަމަންތެރިކަން ބޮޑުވެގެންވާ ޝައިތާނާއަށް މެނުވީ، އެއުރެން އަޅުކަމެއް ނުކުރެތެވެ.","",""],["₄ سورة النساء","118","لَّعَنَهُ ٱللَّهُۘ وَقَالَ لَأَتَّخِذَنَّ مِنۡ عِبَادِكَ نَصِيبٗا مَّفۡرُوضٗا ١١٨","لعنه الله وقال لأتخذن من عبادك نصيبا مفروضا","ﷲ، އެ ޝައިތާނާއަށް ލައުނަތް ލައްވާފައިވެއެވެ. އެ ޝައިތާނާ ބުންޏެވެ. އިބަރަސްކަލާނގެ އަޅުތަކުންގެ ތެރެއިން ކަނޑައެޅިގެންވާ ބަޔެއް، ހަމަކަށަވަރުން، ތިމަން ހިފާހުށީމެވެ.","",""],["₄ سورة النساء","119","وَلَأُضِلَّنَّهُمۡ وَلَأُمَنِّيَنَّهُمۡ وَلَأٓمُرَنَّهُمۡ فَلَيُبَتِّكُنَّ ءَاذَانَ ٱلۡأَنۡعَٰمِ وَلَأٓمُرَنَّهُمۡ فَلَيُغَيِّرُنَّ خَلۡقَ ٱللَّهِۚ وَمَن يَتَّخِذِ ٱلشَّيۡطَٰنَ وَلِيّٗا مِّن دُونِ ٱللَّهِ فَقَدۡ خَسِرَ خُسۡرَانٗا مُّبِينٗا ١١٩","ولأضلنهم ولأمنينهم ولآمرنهم فليبتكن آذان الأنعام ولآمرنهم فليغيرن خلق الله ومن يتخذ الشيطان وليا من دون الله فقد خسر خسرانا مبينا","އަދި، ތިމަން ހަމަކަށަވަރުން، އެއުރެން މަގުފުރައްދާހުށީމެވެ. އަދި، ތިމަން އެއުރެން ލައްވައި، ހަގީގަތެއްނެތް އުންމީދު ތަކެއްވެސް ކުރުވާހުށީމެވެ. އަދި، ގެރި، ބަކަރި، ޖަމަލުގެ ކަންފަތްތައް ކެނޑުމަށްވެސް އެއުރެންނަށް ތިމަން އަމުރުކުރާހުށީމެވެ. އަދި، ﷲގެ ދީން ބަދަލުކުރުމަށްވެސް އެއުރެންނަށް ތިމަން އަމުރުކުރާހުށީމެވެ. ﷲ ފިޔަވައި ޝައިތާނާ އެއީ އެހީތެރިޔަކު ކަމުގައި ހަދައިފިމީހާ (ދަންނާށެވެ!) ފަހެ، ބަޔާން ވެގެންވާ ގެއްލެނިވުމަކުން އެމީހާ ގެއްލެނިވެއްޖެކަން ކަށަވަރެވެ.","",""],["₄ سورة النساء","120","يَعِدُهُمۡ وَيُمَنِّيهِمۡۖ وَمَا يَعِدُهُمُ ٱلشَّيۡطَٰنُ إِلَّا غُرُورًا ١٢٠","يعدهم ويمنيهم وما يعدهم الشيطان إلا غرورا","ޝައިތާނާ އެއުރެންނަށް ވައުދުކުރެތެވެ. އަދި، އެއުރެންލައްވައި ބާތިލު އުންމީދު ކުރުވަތެވެ. އަދި، ހެއްލުންތެރިކަން މެނުވީ ޝައިތާނާ އެއުރެންނަކަށް ވައުދެއް ނުކުރެތެވެ.","",""],["₄ سورة النساء","121","أُوْلَـٰٓئِكَ مَأۡوَىٰهُمۡ جَهَنَّمُ وَلَا يَجِدُونَ عَنۡهَا مَحِيصٗا ١٢١","أولئك مأواهم جهنم ولا يجدون عنها محيصا","އެއުރެން ތިބެނިވި ތަނަކީ، ނަރަކަޔެވެ. އަދި، އެތަނުން އެއުރެން ފިލައިގެން ދާނެތަނެއް ނުމެފެންނާނޭމެއެވެ.","",""],["₄ سورة النساء","122","وَٱلَّذِينَ ءَامَنُواْ وَعَمِلُواْ ٱلصَّـٰلِحَٰتِ سَنُدۡخِلُهُمۡ جَنَّـٰتٖ تَجۡرِي مِن تَحۡتِهَا ٱلۡأَنۡهَٰرُ خَٰلِدِينَ فِيهَآ أَبَدٗاۖ وَعۡدَ ٱللَّهِ حَقّٗاۚ وَمَنۡ أَصۡدَقُ مِنَ ٱللَّهِ قِيلٗا ١٢٢","والذين آمنوا وعملوا الصالحات سندخلهم جنات تجري من تحتها الأنهار خالدين فيها أبدا وعد الله حقا ومن أصدق من الله قيلا","އަދި، އީމާންވެ، ސާލިހު ޢަމަލުކުޅަމީހުން، އެ ސުވަރުގެތަކުގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކަށް، ތިމަންރަސްކަލާނގެ އެއުރެން ވައްދަވާހުށީމެވެ. އެތާނގައި އަބަދަށް ދެމިތިބެނިވި ގޮތުގައެވެ. ﷲ، ވައުދުކުރައްވާފައިވަނީ ހައްގު ތެދެވެ. ބަސްބުނުމުގައި ﷲއަށްވުރެ ތެދުވެރިކަންބޮޑީ ކާކުހެއްޔެވެ؟","",""],["₄ سورة النساء","123","لَّيۡسَ بِأَمَانِيِّكُمۡ وَلَآ أَمَانِيِّ أَهۡلِ ٱلۡكِتَٰبِۗ مَن يَعۡمَلۡ سُوٓءٗا يُجۡزَ بِهِۦ وَلَا يَجِدۡ لَهُۥ مِن دُونِ ٱللَّهِ وَلِيّٗا وَلَا نَصِيرٗا ١٢٣","ليس بأمانيكم ولا أماني أهل الكتاب من يعمل سوءا يجز به ولا يجد له من دون الله وليا ولا نصيرا","(އެކަން ލިބުންވަނީ) ތިޔަބައިމީހުންގެ އެދުންތަކަކުން ނޫނެވެ. އަދި، ފޮތުގެ އަހުލުވެރިންގެ އެދުންތަކަކުންވެސް ނޫނެވެ. ނުބައިކަމެއް ކުރާމީހާޔަށް އެކަމުގެ ޖަޒާ ލިބޭނެތެވެ. އަދި، ﷲ ފިޔަވައި އެހީތެރިޔަކުވެސް އަދި، ނަސްރުވެރިޔަކުވެސް އެމީހަކަށް ނުފެންނާނެތެވެ.","",""],["₄ سورة النساء","124","وَمَن يَعۡمَلۡ مِنَ ٱلصَّـٰلِحَٰتِ مِن ذَكَرٍ أَوۡ أُنثَىٰ وَهُوَ مُؤۡمِنٞ فَأُوْلَـٰٓئِكَ يَدۡخُلُونَ ٱلۡجَنَّةَ وَلَا يُظۡلَمُونَ نَقِيرٗا ١٢٤","ومن يعمل من الصالحات من ذكر أو أنثى وهو مؤمن فأولئك يدخلون الجنة ولا يظلمون نقيرا","އަދި، މުއުމިނަކު ކަމުގައި ވެގެންހުރެ، ފިރިހެނުންނާއި، އަންހެނުންގެ ތެރެއިން ހެޔޮ ޢަމަލުކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެން ސުވަރުގެޔަށް ވަންނާނެތެވެ. އަދި، ކިތަންމެ ކުޑަ މިންވަރަކުންވިޔަސް އެއުރެންނަށް އަނިޔާއެއް ނުކުރައްވާހުށްޓެވެ.","",""],["₄ سورة النساء","125","وَمَنۡ أَحۡسَنُ دِينٗا مِّمَّنۡ أَسۡلَمَ وَجۡهَهُۥ لِلَّهِ وَهُوَ مُحۡسِنٞ وَٱتَّبَعَ مِلَّةَ إِبۡرَٰهِيمَ حَنِيفٗاۗ وَٱتَّخَذَ ٱللَّهُ إِبۡرَٰهِيمَ خَلِيلٗا ١٢٥","ومن أحسن دينا ممن أسلم وجهه لله وهو محسن واتبع ملة إبراهيم حنيفا واتخذ الله إبراهيم خليلا","ހެޔޮކަންތައްކުރާ މީހަކުކަމުގައިވާ ޙާލު، އެމީހެއްގެ އެންމެހައި ކަންތައް ﷲއަށް ކިޔަމަންކޮށް، އަދި ބާތިލު މަގުން އެއްކިބާވެ، ހައްގުގެ މަގަށް ތަބާ ވެގެންވާ އިބްރާހީމްގެފާނުގެ ދީނަށް ތަބާވި މީހަކަށްވުރެ، ދީންގެ ގޮތުން ހެޔޮކަންބޮޑީ ކާކުހެއްޔެވެ؟ ﷲ، މިތުރަކު ކަމުގައި އިބްރާހީމްގެފާނު ހިއްޕެވިއެވެ.","",""],["₄ سورة النساء","126","وَلِلَّهِ مَا فِي ٱلسَّمَٰوَٰتِ وَمَا فِي ٱلۡأَرۡضِۚ وَكَانَ ٱللَّهُ بِكُلِّ شَيۡءٖ مُّحِيطٗا ١٢٦","ولله ما في السماوات وما في الأرض وكان الله بكل شيء محيطا","އަދި، އުޑުތަކާއި، ބިމުގައި ވާހައި އެއްޗެއް މިލްކުވެގެންވަނީ ﷲއަށެވެ. އަދި، ކޮންމެ އެއްޗަކާއި، ކޮންމެކަމެއްމެ، ފުރިހަމަޔަށް ދެނެވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","127","وَيَسۡتَفۡتُونَكَ فِي ٱلنِّسَآءِۖ قُلِ ٱللَّهُ يُفۡتِيكُمۡ فِيهِنَّ وَمَا يُتۡلَىٰ عَلَيۡكُمۡ فِي ٱلۡكِتَٰبِ فِي يَتَٰمَى ٱلنِّسَآءِ ٱلَّـٰتِي لَا تُؤۡتُونَهُنَّ مَا كُتِبَ لَهُنَّ وَتَرۡغَبُونَ أَن تَنكِحُوهُنَّ وَٱلۡمُسۡتَضۡعَفِينَ مِنَ ٱلۡوِلۡدَٰنِ وَأَن تَقُومُواْ لِلۡيَتَٰمَىٰ بِٱلۡقِسۡطِۚ وَمَا تَفۡعَلُواْ مِنۡ خَيۡرٖ فَإِنَّ ٱللَّهَ كَانَ بِهِۦ عَلِيمٗا ١٢٧","ويستفتونك في النساء قل الله يفتيكم فيهن وما يتلى عليكم في الكتاب في يتامى النساء اللاتي لا تؤتونهن ما كتب لهن وترغبون أن تنكحوهن والمستضعفين من الولدان وأن تقوموا لليتامى بالقسط وما تفعلوا من خير فإن الله كان به عليما","އަންހެނުންނާމެދު، ކަލޭގެފާނުގެ އަރިހުން އެއުރެން ފަތުވާއަށް އެދި ދަންނަވަތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲ ތިޔަބައިމީހުންނަށް އެކަނބަލުންނާމެދު ބަޔާން ކޮށް ދެއްވަތެވެ. އަދި، ފޮތުން ތިޔަބައިމީހުންނަށް ކިޔަވައިދެއްވާ އާޔަތްތައްވެސް ބަޔާން ކޮށް ދެއްވަތެވެ. އެކަނބަލުންނަށްޓަކައި ކަނޑައަޅުއްވާފައިވާ ރަން، ތިޔަބައިމީހުން އެކަނބަލުންނަށް ނުދޭ، އަދި އެކަނބަލުންނާ ކާވެނިވުމަށް ތިޔަބައިމީހުން އެދޭ ޔަތީމު އަންހެނުންނާ މެދުގައެވެ. އަދި، ކުޑަކުދިންގެ ތެރެއިން ނިކަމެތިވެފައިވާ ކުދިންނާ މެދުގައެވެ. އަދި، ޔަތީމުންނާމެދު ޢަދުލު އިންޞާފުގެ ގޮތުގައި ކަންތައް ކުރުމަށެވެ. ހެޔޮކަމުގެ ތެރެއިން ތިޔަބައިމީހުން ކުރާ ކަންތައް، ފަހެ ހަމަކަށަވަރުން، އެކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","128","وَإِنِ ٱمۡرَأَةٌ خَافَتۡ مِنۢ بَعۡلِهَا نُشُوزًا أَوۡ إِعۡرَاضٗا فَلَا جُنَاحَ عَلَيۡهِمَآ أَن يُصۡلِحَا بَيۡنَهُمَا صُلۡحٗاۚ وَٱلصُّلۡحُ خَيۡرٞۗ وَأُحۡضِرَتِ ٱلۡأَنفُسُ ٱلشُّحَّۚ وَإِن تُحۡسِنُواْ وَتَتَّقُواْ فَإِنَّ ٱللَّهَ كَانَ بِمَا تَعۡمَلُونَ خَبِيرٗا ١٢٨","وإن امرأة خافت من بعلها نشوزا أو إعراضا فلا جناح عليهما أن يصلحا بينهما صلحا والصلح خير وأحضرت الأنفس الشح وإن تحسنوا وتتقوا فإن الله كان بما تعملون خبيرا","ފިރިމީހާ ދުރުހެލިވެ، ނުވަތަ ވާހަކަ ނުދައްކައި ހުރެދާނެކަމަށް އަންހެނަކަށް ބިރު ހީވެއްޖެނަމަ، އެދެމީހުންގެ މެދުގައި އެކުވެރިކަމުގެ ސުލްހަ ވުމަކުން ސުލްހަ ވުމާމެދު، އެ ދެމީހުންގެ މައްޗަކަށް ކުށެއްނެތެވެ. ސުލްހަ ވުން ހެޔޮކަން ބޮޑެވެ. އަދި (ތިމާގެގާތުން ކުރަންޖެހޭ ހޭދަޔަކާމެދު، އަދި ތިމާޔަށް ލިބެންވީ ލިބުމަކާމެދު) ދަހިވެތިވުން ހިތްތަކުގައި ލައްވާފައިވެއެވެ. އަދި، ތިޔަބައިމީހުން އިހްސާން ތެރިވެ އަދި ތަގުވާވެރިވާނަމަ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ކަންތައްކުރާގޮތް މޮޅަށް ދެނެވޮޑިގެންވާ ކަލަކުކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","129","وَلَن تَسۡتَطِيعُوٓاْ أَن تَعۡدِلُواْ بَيۡنَ ٱلنِّسَآءِ وَلَوۡ حَرَصۡتُمۡۖ فَلَا تَمِيلُواْ كُلَّ ٱلۡمَيۡلِ فَتَذَرُوهَا كَٱلۡمُعَلَّقَةِۚ وَإِن تُصۡلِحُواْ وَتَتَّقُواْ فَإِنَّ ٱللَّهَ كَانَ غَفُورٗا رَّحِيمٗا ١٢٩","ولن تستطيعوا أن تعدلوا بين النساء ولو حرصتم فلا تميلوا كل الميل فتذروها كالمعلقة وإن تصلحوا وتتقوا فإن الله كان غفورا رحيما","ތިޔަބައިމީހުން ކިތަންމެ ވަރަކަށް އެދި ދަހިވެތިވިޔަސް، އަނބިންގެ މެދުގައި (ލޯބީގެގޮތުން) ޢަދުލުވެރިވުމަކަށް ތިޔަބައިމީހުންނަކަށް ކުޅަދާނަވެގެނެއް ނުވާނެތެވެ. ފަހެ، ތިޔަބައިމީހުން (އެކެއްގެ ފަރާތް ދޫކޮށް) މުޅިން ލެނބުމަކުން ނުލެނބޭށެވެ! އެލުވާފައިވާ މީހެއް ފަދައިން އެކަނބުލޭގެ ދޫކޮށްލާ ގޮތުގައެވެ. (އެބަހީ: ވަރިވެސް ނުކޮށް، ސުލްހަ ވުމެއްވެސްނެތި އިނދެގެންމެ، ނީނދެ އުޅޭގޮތަށް އެއް އަނތްބަކާ އަޅައިނުލައި، އަނެއް އަނތްބެއްގެ ފަރާތަށް މުޅިން ލެނބިގެން ނުދާށެވެ!) އަދި، ތިޔަބައިމީހުން (އެކަން) އިސްލާހު ކޮށް ތަގުވާވެރިވާނަމަ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","130","وَإِن يَتَفَرَّقَا يُغۡنِ ٱللَّهُ كُلّٗا مِّن سَعَتِهِۦۚ وَكَانَ ٱللَّهُ وَٰسِعًا حَكِيمٗا ١٣٠","وإن يتفرقا يغن الله كلا من سعته وكان الله واسعا حكيما","އަދި، އެ ދެމީހުން ވަކިވާނަމަ، ﷲގެ ތަނަވަސްކަމުގެ ތެރެއިން، އެ ދެމީހުންކުރެ ކޮންމެ މީހަކަށްމެ، ފުއްދަވައި ދެއްވާނެތެވެ. ތަނަވަސްވަންތަ ޙަކީމްވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","131","وَلِلَّهِ مَا فِي ٱلسَّمَٰوَٰتِ وَمَا فِي ٱلۡأَرۡضِۗ وَلَقَدۡ وَصَّيۡنَا ٱلَّذِينَ أُوتُواْ ٱلۡكِتَٰبَ مِن قَبۡلِكُمۡ وَإِيَّاكُمۡ أَنِ ٱتَّقُواْ ٱللَّهَۚ وَإِن تَكۡفُرُواْ فَإِنَّ لِلَّهِ مَا فِي ٱلسَّمَٰوَٰتِ وَمَا فِي ٱلۡأَرۡضِۚ وَكَانَ ٱللَّهُ غَنِيًّا حَمِيدٗا ١٣١","ولله ما في السماوات وما في الأرض ولقد وصينا الذين أوتوا الكتاب من قبلكم وإياكم أن اتقوا الله وإن تكفروا فإن لله ما في السماوات وما في الأرض وكان الله غنيا حميدا","އަދި، އުޑުތަކާއި، ބިމުގައި ވާހައި އެއްޗެއް މިލްކުވެގެންވަނީ، ﷲއަށެވެ. އަދި، ހަމަކަށަވަރުން، ﷲއަށް ތަގުވާވެރިވުމަށް ތިޔަބައިމީހުންގެ ކުރިން ފޮތް ލިބުނު މީހުންނަށާއި، ތިޔަބައިމީހުންނަށް، ތިމަންރަސްކަލާނގެ ވަސިއްޔަތްކުރައްވައި އެންގެވީމެވެ. ތިޔަބައިމީހުން ކާފިރު ވާނަމަ (ދަންނާށެވެ!) ހަމަކަށަވަރުން، އުޑުތަކުގައި ވާހައި ތަކެއްޗާއި، ބިމުގައި ވާހައި ތަކެއްޗެއް މިލްކުވެގެންވަނީ ﷲއަށެވެ. ފުދިވޮޑިގެންވާ ހަމްދު ލިބިވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","132","وَلِلَّهِ مَا فِي ٱلسَّمَٰوَٰتِ وَمَا فِي ٱلۡأَرۡضِۚ وَكَفَىٰ بِٱللَّهِ وَكِيلًا ١٣٢","ولله ما في السماوات وما في الأرض وكفى بالله وكيلا","އަދި، އުޑުތަކާއި، ބިމުގައި ވާހައި އެއްޗެއް މިލްކުވެގެންވަނީ ﷲއަށެވެ. ވަކީލަކުކަމުގައި ﷲ ފުދެއެވެ.","",""],["₄ سورة النساء","133","إِن يَشَأۡ يُذۡهِبۡكُمۡ أَيُّهَا ٱلنَّاسُ وَيَأۡتِ بِـَٔاخَرِينَۚ وَكَانَ ٱللَّهُ عَلَىٰ ذَٰلِكَ قَدِيرٗا ١٣٣","إن يشأ يذهبكم أيها الناس ويأت بآخرين وكان الله على ذلك قديرا","އޭ މީސްތަކުންނޭވެ! އެކަލާނގެ އިރާދަކުރައްވާނަމަ، ތިޔަބައިމީހުން ނެތިކުރައްވައިފީހެވެ. އަދި (ތިޔަބައިމީހުންގެ ބަދަލުގައި) އެހެންބަޔަކު އުފައްދަވައިފީހެވެ. އެކަމުގެ މައްޗަށް ކުޅަދުންވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","134","مَّن كَانَ يُرِيدُ ثَوَابَ ٱلدُّنۡيَا فَعِندَ ٱللَّهِ ثَوَابُ ٱلدُّنۡيَا وَٱلۡأٓخِرَةِۚ وَكَانَ ٱللَّهُ سَمِيعَۢا بَصِيرٗا ١٣٤","من كان يريد ثواب الدنيا فعند الله ثواب الدنيا والآخرة وكان الله سميعا بصيرا","ދުނިޔޭގެ ސަވާބު އެދޭކަމުގައިވާ މީހާ (ދަންނާށެވެ!) ފަހެ، ދުނިޔެއާއި އާޚިރަތްގެ ސަވާބު ވަނީ، ﷲގެ ހަޒުރަތު ގައެވެ. މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ބައްލަވާވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","135","۞يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ كُونُواْ قَوَّـٰ‌مِينَ بِٱلۡقِسۡطِ شُهَدَآءَ لِلَّهِ وَلَوۡ عَلَىٰٓ أَنفُسِكُمۡ أَوِ ٱلۡوَٰلِدَيۡنِ وَٱلۡأَقۡرَبِينَۚ إِن يَكُنۡ غَنِيًّا أَوۡ فَقِيرٗا فَٱللَّهُ أَوۡلَىٰ بِهِمَاۖ فَلَا تَتَّبِعُواْ ٱلۡهَوَىٰٓ أَن تَعۡدِلُواْۚ وَإِن تَلۡوُۥٓاْ أَوۡ تُعۡرِضُواْ فَإِنَّ ٱللَّهَ كَانَ بِمَا تَعۡمَلُونَ خَبِيرٗا ١٣٥","يا أيها الذين آمنوا كونوا قوامين بالقسط شهداء لله ولو على أنفسكم أو الوالدين والأقربين إن يكن غنيا أو فقيرا فالله أولى بهما فلا تتبعوا الهوى أن تعدلوا وإن تلووا أو تعرضوا فإن الله كان بما تعملون خبيرا","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ޢަދުލު އިންޞާފު ގާއިމުކުރުމުގައި ދެމިތިބޭ ބަޔަކު ކަމުގައިވާށެވެ! (އަދި) ﷲއަށްޓަކައި ހެކިބަސް އަދާކުރާ ބަޔަކު ކަމުގައި ތިޔަބައިމީހުންވާށެވެ! ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތަކުގެ މައްޗަށް ކަމުގައިވިޔަސް، ނުވަތަ މައިންބަފައިންނާއި، ގާތްތިމާގެ މީހުންގެ މައްޗަށް ކަމުގައިވިޔަސް މެއެވެ. އެމީހަކީ (އެބަހީ: އެމީހެއްގެ މައްޗަށް ހެކިދެވޭ މީހަކީ) މުއްސަންޖަކު ކަމުގައި، ނުވަތަ ފަގީރަކު ކަމުގައިވިޔަސް، ފަހެ، އެދެމީހުންނަށްމެ، ﷲ، އައުލާ ކަން ބޮޑެވެ. ތިޔަބައިމީހުން ޢަދުލުވެރިވުން ދޫކޮށް އަމިއްލަ އެދުމަށް ތަބާ ނުވާށެވެ! އަދި، ތިޔަބައިމީހުން ހެކިބަސް ބަދަލުކުޅަނަމަ، ނުވަތަ ހެކިބަސް އަދާކުރުމުން އެއްކިބާވާނަމަ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ކުރާ ޢަމަލުތައް މޮޅަށް ދެނެވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","136","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ ءَامِنُواْ بِٱللَّهِ وَرَسُولِهِۦ وَٱلۡكِتَٰبِ ٱلَّذِي نَزَّلَ عَلَىٰ رَسُولِهِۦ وَٱلۡكِتَٰبِ ٱلَّذِيٓ أَنزَلَ مِن قَبۡلُۚ وَمَن يَكۡفُرۡ بِٱللَّهِ وَمَلَـٰٓئِكَتِهِۦ وَكُتُبِهِۦ وَرُسُلِهِۦ وَٱلۡيَوۡمِ ٱلۡأٓخِرِ فَقَدۡ ضَلَّ ضَلَٰلَۢا بَعِيدًا ١٣٦","يا أيها الذين آمنوا آمنوا بالله ورسوله والكتاب الذي نزل على رسوله والكتاب الذي أنزل من قبل ومن يكفر بالله وملائكته وكتبه ورسله واليوم الآخر فقد ضل ضلالا بعيدا","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށާއި، އެކަލާނގެ ރަސޫލާއަށް ބާވައިލެއްވި ފޮތަށާއި، އަދި، ކުރިން ބާވައިލެއްވި ފޮތަށް އީމާން ވުންމަތީ ތިޔަބައިމީހުން ދެމިތިބޭށެވެ! އަދި، ﷲއަށާއި، އެކަލާނގެ މަލާއިކަތުންނަށާއި، އެކަލާނގެ (ބާވައިލެއްވި) ފޮތްތަކަށާއި، އެކަލާނގެ (ފޮނުއްވި) ރަސޫލުންނަށާއި، އާޚިރަތް ދުވަހަށް ކާފިރު ވާމީހާ (ދަންނާށެވެ!) ފަހެ، އޭނާ ދުރުވެގެންވާ މަގުފުރެދުމަކުން މަގުފުރެދިއްޖެކަން ކަށަވަރެވެ.","",""],["₄ سورة النساء","137","إِنَّ ٱلَّذِينَ ءَامَنُواْ ثُمَّ كَفَرُواْ ثُمَّ ءَامَنُواْ ثُمَّ كَفَرُواْ ثُمَّ ٱزۡدَادُواْ كُفۡرٗا لَّمۡ يَكُنِ ٱللَّهُ لِيَغۡفِرَ لَهُمۡ وَلَا لِيَهۡدِيَهُمۡ سَبِيلَۢا ١٣٧","إن الذين آمنوا ثم كفروا ثم آمنوا ثم كفروا ثم ازدادوا كفرا لم يكن الله ليغفر لهم ولا ليهديهم سبيلا","ހަމަކަށަވަރުން، އީމާން ވެފައި، ދެން ކާފިރު ވެފައި، ދެން އީމާން ވެފައި، ދެން ކާފިރު ވެފައި، ދެން ކާފިރު ކަން އިތުރުވެއްޖެ މީހުންނީ، ﷲއެއުރެންގެ ފާފަފުއްސަވާނޭ ބަޔެއް ނޫނެވެ. އަދި، އެއުރެންނަކީ ތެދުމަގު ދައްކަވާނޭ ބަޔެއްވެސް ނުމެނޫންމެއެވެ.","",""],["₄ سورة النساء","138","بَشِّرِ ٱلۡمُنَٰفِقِينَ بِأَنَّ لَهُمۡ عَذَابًا أَلِيمًا ١٣٨","بشر المنافقين بأن لهم عذابا أليما","ހަމަކަށަވަރުން، މުނާފިގުންނަށް ވޭންދެނިވި އަޒާބު ހުރިކަމުގެ ޚަބަރު ކަލޭގެފާނު އެއުރެންނަށް ދެއްވާށެވެ!","",""],["₄ سورة النساء","139","ٱلَّذِينَ يَتَّخِذُونَ ٱلۡكَٰفِرِينَ أَوۡلِيَآءَ مِن دُونِ ٱلۡمُؤۡمِنِينَۚ أَيَبۡتَغُونَ عِندَهُمُ ٱلۡعِزَّةَ فَإِنَّ ٱلۡعِزَّةَ لِلَّهِ جَمِيعٗا ١٣٩","الذين يتخذون الكافرين أولياء من دون المؤمنين أيبتغون عندهم العزة فإن العزة لله جميعا","އެއުރެންނީ، މުއުމިނުން ފިޔަވައި، ކާފިރުން އެއީ އެހީތެރިން ކަމުގައި ބަލައިގެން އުޅޭ މީހުންނެވެ. އެ ކާފިރުންގެ ގާތުން ޢިއްޒަތް ލިބިގަތުމަށް އެއުރެން އެދެނީހެއްޔެވެ؟ ފަހެ، ހަމަކަށަވަރުން އެންމެހައި ޢިއްޒަތް މިލްކުވެގެންވަނީ ﷲއަށެވެ.","",""],["₄ سورة النساء","140","وَقَدۡ نَزَّلَ عَلَيۡكُمۡ فِي ٱلۡكِتَٰبِ أَنۡ إِذَا سَمِعۡتُمۡ ءَايَٰتِ ٱللَّهِ يُكۡفَرُ بِهَا وَيُسۡتَهۡزَأُ بِهَا فَلَا تَقۡعُدُواْ مَعَهُمۡ حَتَّىٰ يَخُوضُواْ فِي حَدِيثٍ غَيۡرِهِۦٓ إِنَّكُمۡ إِذٗا مِّثۡلُهُمۡۗ إِنَّ ٱللَّهَ جَامِعُ ٱلۡمُنَٰفِقِينَ وَٱلۡكَٰفِرِينَ فِي جَهَنَّمَ جَمِيعًا ١٤٠","وقد نزل عليكم في الكتاب أن إذا سمعتم آيات الله يكفر بها ويستهزأ بها فلا تقعدوا معهم حتى يخوضوا في حديث غيره إنكم إذا مثلهم إن الله جامع المنافقين والكافرين في جهنم جميعا","ހަމަކަށަވަރުން، ފޮތުގައި ތިޔަބައިމީހުންގެ މައްޗަށް ބާވައިލައްވާފައިވެއެވެ. ﷲގެ އާޔަތްތަކަށް ކާފިރުވެ، އެ އާޔަތްތަކަށް މަލާމާތްކުރާ އަޑު ތިޔަބައިމީހުންނަށް އިވޭހިނދު، އެއުރެން އެހެން ވާހަކަޔެއް ދައްކަން ފަށައިފުމަށް ދާންދެން، އެއުރެންނާއެކު، ތިޔަބައިމީހުން ނުތިބޭށެވެ! އެހެން ތިޔަބައިމީހުން ތިބެނީނަމަ، ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަކީވެސް އެއުރެންފަދަ ބަޔެކެވެ. ހަމަކަށަވަރުން، ﷲ، މުނާފިގްނާއި ކާފިރުންގެ އެންމެން ނަރަކަޔަށް އެއްކުރައްވާނެތެވެ.","",""],["₄ سورة النساء","141","ٱلَّذِينَ يَتَرَبَّصُونَ بِكُمۡ فَإِن كَانَ لَكُمۡ فَتۡحٞ مِّنَ ٱللَّهِ قَالُوٓاْ أَلَمۡ نَكُن مَّعَكُمۡ وَإِن كَانَ لِلۡكَٰفِرِينَ نَصِيبٞ قَالُوٓاْ أَلَمۡ نَسۡتَحۡوِذۡ عَلَيۡكُمۡ وَنَمۡنَعۡكُم مِّنَ ٱلۡمُؤۡمِنِينَۚ فَٱللَّهُ يَحۡكُمُ بَيۡنَكُمۡ يَوۡمَ ٱلۡقِيَٰمَةِۗ وَلَن يَجۡعَلَ ٱللَّهُ لِلۡكَٰفِرِينَ عَلَى ٱلۡمُؤۡمِنِينَ سَبِيلًا ١٤١","الذين يتربصون بكم فإن كان لكم فتح من الله قالوا ألم نكن معكم وإن كان للكافرين نصيب قالوا ألم نستحوذ عليكم ونمنعكم من المؤمنين فالله يحكم بينكم يوم القيامة ولن يجعل الله للكافرين على المؤمنين سبيلا","އެއުރެންނީ، ތިޔަބައިމީހުންނާމެދު، ބަލަބަލައި ތިބޭ މީހުންނެވެ. ފަހެ، ﷲގެ ހަޒުރަތުން، ތިޔަބައިމީހުންނަށް ފަތަޙެއް ލިބިއްޖެނަމަ، އެއުރެން ބުނެތެވެ. ތިމަންމެން ތިޔަބައިމީހުންނާ އެކުގައި ނުވަންހޭ؟ އަދި، ކާފިރުންނަށް ނަސީބެއް ލިބިއްޖެނަމަ އެއުރެން ބުނެތެވެ. ތިޔަބައިމީހުންގެ މައްޗަށް ތިމަންމެން ގަދަވެ ނުގަންނަންހޭ؟ އަދި، މުއުމިނުންގެ ކިބައިން ތިޔަބައިމީހުން ރައްކާތެރިކޮށް ނުދެންހޭ؟ ގިޔާމަތް ދުވަހުން ތިޔަބައިމީހުންގެ މެދުގައި ހުކުމްކުރައްވާހުށީ ﷲއެވެ. އަދި، މުއުމިނުންގެ މައްޗަށް ކާފިރުންނަކަށް އެއްވެސް މަގެއް ﷲ ނުލައްވާނެތެވެ.","",""],["₄ سورة النساء","142","إِنَّ ٱلۡمُنَٰفِقِينَ يُخَٰدِعُونَ ٱللَّهَ وَهُوَ خَٰدِعُهُمۡ وَإِذَا قَامُوٓاْ إِلَى ٱلصَّلَوٰةِ قَامُواْ كُسَالَىٰ يُرَآءُونَ ٱلنَّاسَ وَلَا يَذۡكُرُونَ ٱللَّهَ إِلَّا قَلِيلٗا ١٤٢","إن المنافقين يخادعون الله وهو خادعهم وإذا قاموا إلى الصلاة قاموا كسالى يراءون الناس ولا يذكرون الله إلا قليلا","ހަމަކަށަވަރުން، މުނާފިގުން، ﷲއަށް އޮޅުވައިލަތެވެ. (އެބަހީ: އޮޅުވައިލުމަށްކުރާ ކަހަލަ ޢަމަލުތައް ކުރެތެވެ.) އެކަލާނގެ އެއުރެންގެ މައްޗަށް އެ އޮޅުވައިލުން ރައްދުކުރައްވާ ހުށްޓެވެ. އަދި، އެއުރެން ނަމާދަށް ތެދުވާއިރު، މީސްތަކުންނަށް ކަންދައްކަމުން ކަންނެތްވެ ތިބެ ތެދުވެތެވެ. އަދި، ވަރަށް މަދުންމެނުވީ، އެއުރެން ﷲ ހަނދުމައެއް ނުކުރެތެވެ.","",""],["₄ سورة النساء","143","مُّذَبۡذَبِينَ بَيۡنَ ذَٰلِكَ لَآ إِلَىٰ هَـٰٓؤُلَآءِ وَلَآ إِلَىٰ هَـٰٓؤُلَآءِۚ وَمَن يُضۡلِلِ ٱللَّهُ فَلَن تَجِدَ لَهُۥ سَبِيلٗا ١٤٣","مذبذبين بين ذلك لا إلى هؤلاء ولا إلى هؤلاء ومن يضلل الله فلن تجد له سبيلا","އެދެމެދުގައި (އެބަހީ: އީމާންކަމާއި ކާފިރުކަމާ ދެމެދުގައި) ދެއަތަށް ކިރިކިރިތިބޭ ޙާލު ގައެވެ. މިބަޔަކަށްވެސް ނޫނެވެ. އަދި، އެބަޔަކަށްވެސް ނޫނެވެ. (އެބަހީ: މުއުމިނުންގެ ޖަމާއަތަކަށްވެސް، އަދި، ކާފިރުންގެ ޖަމާއަތަކަށްވެސް އެއުރެން ނިސްބަތެއް ނުވެއެވެ.) ﷲ، މަގުފުރައްދަވާ މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށްޓަކައި އެއްވެސްމަގެއް ކަލޭގެފާނަކަށް ފެނިވަޑައެއް ނުގަންނަވާނެތެވެ.","",""],["₄ سورة النساء","144","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تَتَّخِذُواْ ٱلۡكَٰفِرِينَ أَوۡلِيَآءَ مِن دُونِ ٱلۡمُؤۡمِنِينَۚ أَتُرِيدُونَ أَن تَجۡعَلُواْ لِلَّهِ عَلَيۡكُمۡ سُلۡطَٰنٗا مُّبِينًا ١٤٤","يا أيها الذين آمنوا لا تتخذوا الكافرين أولياء من دون المؤمنين أتريدون أن تجعلوا لله عليكم سلطانا مبينا","އޭއީމާން ވެއްޖެ މީސްތަކުންނޭވެ! މުއުމިނުން ފިޔަވައި، ކާފިރުން އެއީ އެހީތެރިން ކަމުގައި ތިޔަބައިމީހުން ނުހިފާށެވެ! (ފަހެ) ބަޔާން ވެގެންވާ ހުއްޖަތެއް ތިޔަބައިމީހުންނާ ދެކޮޅަށް، ތިޔަބައިމީހުން ﷲގެ ހަޒުރަތަށް ހުށަހެޅުމަށް އެދެނީހެއްޔެވެ؟","",""],["₄ سورة النساء","145","إِنَّ ٱلۡمُنَٰفِقِينَ فِي ٱلدَّرۡكِ ٱلۡأَسۡفَلِ مِنَ ٱلنَّارِ وَلَن تَجِدَ لَهُمۡ نَصِيرًا ١٤٥","إن المنافقين في الدرك الأسفل من النار ولن تجد لهم نصيرا","ހަމަކަށަވަރުން، މުނާފިގުން ވާހުށީ، ނަރަކައިގެ އެންމެ ދަށުވަތްގަނޑުގައެވެ. އަދި، އެއުރެންނަށް ނަސްރުވެރިވާނޭ އެއްވެސް ފަރާތެއް ކަލޭގެފާނު ދެކެވަޑައެއް ނުގަންނަވާނޫއެވެ.","",""],["₄ سورة النساء","146","إِلَّا ٱلَّذِينَ تَابُواْ وَأَصۡلَحُواْ وَٱعۡتَصَمُواْ بِٱللَّهِ وَأَخۡلَصُواْ دِينَهُمۡ لِلَّهِ فَأُوْلَـٰٓئِكَ مَعَ ٱلۡمُؤۡمِنِينَۖ وَسَوۡفَ يُؤۡتِ ٱللَّهُ ٱلۡمُؤۡمِنِينَ أَجۡرًا عَظِيمٗا ١٤٦","إلا الذين تابوا وأصلحوا واعتصموا بالله وأخلصوا دينهم لله فأولئك مع المؤمنين وسوف يؤت الله المؤمنين أجرا عظيما","އެއުރެން ތައުބާވެ، އަދި ޢަމަލުތައް އިސްލާހު ކޮށް، އަދި ﷲގެ ދީންގައި ގަދަޔަށް ހިފަހައްޓައި، އެއުރެންގެ ދީން، ﷲއަށް ޚަލާޞްކުޅަ މީހުން މެނުވީއެވެ. ފަހެ، އެއުރެންވަނީ މުއުމިނުންގެ ތެރެއިންނެވެ. އަދި، މުއުމިނުންނަށް ބޮޑުވެގެންވާ ދަރުމަ، ﷲ ދެއްވާނެތެވެ.","",""],["₄ سورة النساء","147","مَّا يَفۡعَلُ ٱللَّهُ بِعَذَابِكُمۡ إِن شَكَرۡتُمۡ وَءَامَنتُمۡۚ وَكَانَ ٱللَّهُ شَاكِرًا عَلِيمٗا ١٤٧","ما يفعل الله بعذابكم إن شكرتم وآمنتم وكان الله شاكرا عليما","ތިޔަބައިމީހުން ޝުކުރު ކޮށް، އީމާން ވީނަމަ، ތިޔަބައިމީހުންނަށް އަޒާބު ދެއްވުމުން ﷲކުރައްވާނީ ކޮންކަމެއްހެއްޔެވެ؟ (އެބަހީ: އެފަދަ މީހުންނަށް ﷲ އަޒާބު ނުދެއްވާނެކަން ކަނޑައެޅުއްވުމެވެ.) ޝުކުރު ގަބޫލުކުރައްވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ކަލަކުކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","148","۞لَّا يُحِبُّ ٱللَّهُ ٱلۡجَهۡرَ بِٱلسُّوٓءِ مِنَ ٱلۡقَوۡلِ إِلَّا مَن ظُلِمَۚ وَكَانَ ٱللَّهُ سَمِيعًا عَلِيمًا ١٤٨","لا يحب الله الجهر بالسوء من القول إلا من ظلم وكان الله سميعا عليما","އަނިޔާ ލިބިގެންވާމީހާ މެނުވީ، ނުބައިބަސްބުނެ، ފާޅުކުރުމަކަށް ﷲ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ. އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","149","إِن تُبۡدُواْ خَيۡرًا أَوۡ تُخۡفُوهُ أَوۡ تَعۡفُواْ عَن سُوٓءٖ فَإِنَّ ٱللَّهَ كَانَ عَفُوّٗا قَدِيرًا ١٤٩","إن تبدوا خيرا أو تخفوه أو تعفوا عن سوء فإن الله كان عفوا قديرا","ތިޔަބައިމީހުން ހެޔޮކަމެއް ފާޅުކުރާނަމަ، ނުވަތަ ހެޔޮކަމެއް ވަންހަނާކުރާނަމަ، ނުވަތަ ނުބައިކަމަކުން އަފޫކުރާނަމަ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ގިނަގިނައިން އަފޫކުރައްވާ ކުޅަދުންވަންތަ ކަލަކުކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","150","إِنَّ ٱلَّذِينَ يَكۡفُرُونَ بِٱللَّهِ وَرُسُلِهِۦ وَيُرِيدُونَ أَن يُفَرِّقُواْ بَيۡنَ ٱللَّهِ وَرُسُلِهِۦ وَيَقُولُونَ نُؤۡمِنُ بِبَعۡضٖ وَنَكۡفُرُ بِبَعۡضٖ وَيُرِيدُونَ أَن يَتَّخِذُواْ بَيۡنَ ذَٰلِكَ سَبِيلًا ١٥٠","إن الذين يكفرون بالله ورسله ويريدون أن يفرقوا بين الله ورسله ويقولون نؤمن ببعض ونكفر ببعض ويريدون أن يتخذوا بين ذلك سبيلا","ހަމަކަށަވަރުން، ﷲއާއި، އެކަލާނގެ ރަސޫލުންނަށް ކާފިރުވާ މީހުންނާއި، ﷲއާއި އެކަލާނގެ ރަސޫލުންނާ ދެމެދު (އީމާން ވުމުގައި) ތަފާތުކުރަން އެދޭމީހުންނާއި، ތިމަންމެން އެއްބަޔަކަށް އީމާން ވަމުއޭ އަދި އަނެއްބަޔަކަށް ކާފިރު ވަމުއޭ ބުނެ، އެދެމެދުން މަގެއް ހިފުމަށް އެދޭމީހުން، (ދަންނާށެވެ!) އެއުރެންނަކީ، ކަނޑައެޅިގެން އެނގޭގޮތުގައި ތިބި ކާފިރުންނެވެ. ކާފިރުންނަށް އިހާނެތި އަޒާބު، ތިމަންރަސްކަލާނގެ ތައްޔާރުކުރެއްވީމެވެ.","",""],["₄ سورة النساء","151","أُوْلَـٰٓئِكَ هُمُ ٱلۡكَٰفِرُونَ حَقّٗاۚ وَأَعۡتَدۡنَا لِلۡكَٰفِرِينَ عَذَابٗا مُّهِينٗا ١٥١","أولئك هم الكافرون حقا وأعتدنا للكافرين عذابا مهينا","ހަމަކަށަވަރުން، ﷲއާއި، އެކަލާނގެ ރަސޫލުންނަށް ކާފިރުވާ މީހުންނާއި، ﷲއާއި އެކަލާނގެ ރަސޫލުންނާ ދެމެދު (އީމާން ވުމުގައި) ތަފާތުކުރަން އެދޭމީހުންނާއި، ތިމަންމެން އެއްބަޔަކަށް އީމާން ވަމުއޭ އަދި އަނެއްބަޔަކަށް ކާފިރު ވަމުއޭ ބުނެ، އެދެމެދުން މަގެއް ހިފުމަށް އެދޭމީހުން، (ދަންނާށެވެ!) އެއުރެންނަކީ، ކަނޑައެޅިގެން އެނގޭގޮތުގައި ތިބި ކާފިރުންނެވެ. ކާފިރުންނަށް އިހާނެތި އަޒާބު، ތިމަންރަސްކަލާނގެ ތައްޔާރުކުރެއްވީމެވެ.","",""],["₄ سورة النساء","152","وَٱلَّذِينَ ءَامَنُواْ بِٱللَّهِ وَرُسُلِهِۦ وَلَمۡ يُفَرِّقُواْ بَيۡنَ أَحَدٖ مِّنۡهُمۡ أُوْلَـٰٓئِكَ سَوۡفَ يُؤۡتِيهِمۡ أُجُورَهُمۡۚ وَكَانَ ٱللَّهُ غَفُورٗا رَّحِيمٗا ١٥٢","والذين آمنوا بالله ورسله ولم يفرقوا بين أحد منهم أولئك سوف يؤتيهم أجورهم وكان الله غفورا رحيما","އަދި، ﷲއާއި، އެކަލާނގެ ރަސޫލުންނަށް އީމާންވެ، އެ ރަސޫލު ންކުރެ އެކަކާމެދުވެސް ތަފާތުނުކޮށް އުޅުނުމީހުން (ދަންނާށެވެ!) އެއުރެންނަށް އެކަލާނގެ އެއުރެންގެ ދަރުމަ ނިކަންހުރެ ދެއްވާނެތެވެ. ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","153","يَسۡـَٔلُكَ أَهۡلُ ٱلۡكِتَٰبِ أَن تُنَزِّلَ عَلَيۡهِمۡ كِتَٰبٗا مِّنَ ٱلسَّمَآءِۚ فَقَدۡ سَأَلُواْ مُوسَىٰٓ أَكۡبَرَ مِن ذَٰلِكَ فَقَالُوٓاْ أَرِنَا ٱللَّهَ جَهۡرَةٗ فَأَخَذَتۡهُمُ ٱلصَّـٰعِقَةُ بِظُلۡمِهِمۡۚ ثُمَّ ٱتَّخَذُواْ ٱلۡعِجۡلَ مِنۢ بَعۡدِ مَا جَآءَتۡهُمُ ٱلۡبَيِّنَٰتُ فَعَفَوۡنَا عَن ذَٰلِكَۚ وَءَاتَيۡنَا مُوسَىٰ سُلۡطَٰنٗا مُّبِينٗا ١٥٣","يسألك أهل الكتاب أن تنزل عليهم كتابا من السماء فقد سألوا موسى أكبر من ذلك فقالوا أرنا الله جهرة فأخذتهم الصاعقة بظلمهم ثم اتخذوا العجل من بعد ما جاءتهم البينات فعفونا عن ذلك وآتينا موسى سلطانا مبينا","ފޮތުގެ އަހުލުވެރިން (އެބަހީ: ޔަހޫދީން) އެއުރެންގެ މައްޗަށް ކަލޭގެފާނު އުޑުން ފޮތެއް ބާވައިލައްވައި ދެއްވުމަށް ކަލޭގެފާނުގެ އަރިހުން އެދި ދަންނަވަތެވެ. ފަހެ، ހަމަކަށަވަރުން، އެއަށްވުރެ ބޮޑުކަމަކަށް މޫސާގެފާނުންގެ އަރިހުން އެއުރެން އެދި ދަންނަވާފައިވެއެވެ. ފަހެ، އެއުރެން ދެންނެވޫއެވެ. ތިމަންމެންނަށް، ފާޅުގައި ﷲ ދައްކަވާށެވެ! ދެން، އެއުރެންގެ ނުކިޔަމަންތެރިކަމުގެ ސަބަބުން ހޮނުގުގުރި އެއުރެންގައި ހިފިއެވެ. ދެން، އެއަށްފަހު، ބަޔާން ވެގެންވާ ހެކިތައް އެއުރެންގެ ގާތަށް އައުމަށްފަހު، (އަޅުކަންކުރުމަށް އިލާހެއްގެ ގޮތުގައި) އެއުރެން ގެރި ބޭނުންކުޅައޫއެވެ. ދެންވެސް، ތިމަންރަސްކަލާނގެ އެކަމުގެ ކުށް އަފޫކުރެއްވީމެވެ. އަދި، ބަޔާން ވެގެންވާ ބާރު، މޫސާގެފާނަށް ތިމަންރަސްކަލާނގެ ދެއްވީމެވެ.","",""],["₄ سورة النساء","154","وَرَفَعۡنَا فَوۡقَهُمُ ٱلطُّورَ بِمِيثَٰقِهِمۡ وَقُلۡنَا لَهُمُ ٱدۡخُلُواْ ٱلۡبَابَ سُجَّدٗا وَقُلۡنَا لَهُمۡ لَا تَعۡدُواْ فِي ٱلسَّبۡتِ وَأَخَذۡنَا مِنۡهُم مِّيثَٰقًا غَلِيظٗا ١٥٤","ورفعنا فوقهم الطور بميثاقهم وقلنا لهم ادخلوا الباب سجدا وقلنا لهم لا تعدوا في السبت وأخذنا منهم ميثاقا غليظا","އަދި، ތިމަންރަސްކަލާނގެ، އެއުރެންގެ (ބޮލާދިމާ) މައްޗަށް ޠޫރު ފަރުބަދަ އުފުއްލެވީމެވެ. (އެއީ) އެއުރެންގެ ކަށަވަރުވެގެންވާ އަހުދުގެ ސަބަބުންނެވެ. (އެބަހީ: ތައުރާތުގެ ހުކުމްތަކަށް ޢަމަލުކުރަން، އެއުރެން ވެފައިވާ އަހުދު އުވައިލުމުގެ ސަބަބުންނެވެ.) އަދި، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް އެންގެވީމެވެ. ތިޔަބައިމީހުން ކިޔަމަންތެރިވެގެން ތިބެ (ރަށުގެ) ދޮރޯށިން ވަންނާށެވެ! އަދި، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް އެންގެވީމެވެ. ތިޔަބައިމީހުން ހޮނިހިރު ދުވަހާމެދު، ދެކޮޅުވެރިވެ ނުކިޔަމަންތެރި ވުމުގައި ހައްދުފަހަނަޅައި ނުދާށެވެ! އަދި، ގަދަވެގެންވާ މީޘާގު، އެއުރެންގެ ކިބައިން ތިމަންރަސްކަލާނގެ ހިއްޕެވީމެވެ.","",""],["₄ سورة النساء","155","فَبِمَا نَقۡضِهِم مِّيثَٰقَهُمۡ وَكُفۡرِهِم بِـَٔايَٰتِ ٱللَّهِ وَقَتۡلِهِمُ ٱلۡأَنۢبِيَآءَ بِغَيۡرِ حَقّٖ وَقَوۡلِهِمۡ قُلُوبُنَا غُلۡفُۢۚ بَلۡ طَبَعَ ٱللَّهُ عَلَيۡهَا بِكُفۡرِهِمۡ فَلَا يُؤۡمِنُونَ إِلَّا قَلِيلٗا ١٥٥","فبما نقضهم ميثاقهم وكفرهم بآيات الله وقتلهم الأنبياء بغير حق وقولهم قلوبنا غلف بل طبع الله عليها بكفرهم فلا يؤمنون إلا قليلا","ފަހެ، އެއުރެންގެ އަހުދު އުވާލައި، އަދި އެއުރެން ﷲގެ އާޔަތްތަކަށް ކާފިރުވެ، އަދި ހައްގަކާނުލައި ނަބީބޭކަލުން ގަތުލު ކޮށް، އަދި ތިމަންމެންގެ ހިތްތަކަކީ ބަންދުވެފައިވާ ހިތްތަކެކޭ ބުނެ އުޅުމުގެ ސަބަބުން، (ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ލައުނަތް ލެއްވީމެވެ.) އަދި ކިއެއްތަ! އެއުރެން ކާފިރު ވުމުގެ ސަބަބުން އެ ހިތްތަކުގައި ﷲ ސިއްކަގައްސަވާފައިވެއެވެ. ފަހެ، އެއުރެންކުރެ މަދުބަޔަކު މެނުވީ އީމާނެއް ނުވާނެތެވެ.","",""],["₄ سورة النساء","156","وَبِكُفۡرِهِمۡ وَقَوۡلِهِمۡ عَلَىٰ مَرۡيَمَ بُهۡتَٰنًا عَظِيمٗا ١٥٦","وبكفرهم وقولهم على مريم بهتانا عظيما","އަދި، އެއުރެން ކާފިރު ވުމުގެ ސަބަބުންނާއި، އަދި އެއުރެން މަރިޔަމްގެފާނުގެ މައްޗަށް ބޮޑުވެގެންވާ ބުހުތާނު ދޮގެއް ބުނުމުގެ ސަބަބުންމެއެވެ.","",""],["₄ سورة النساء","157","وَقَوۡلِهِمۡ إِنَّا قَتَلۡنَا ٱلۡمَسِيحَ عِيسَى ٱبۡنَ مَرۡيَمَ رَسُولَ ٱللَّهِ وَمَا قَتَلُوهُ وَمَا صَلَبُوهُ وَلَٰكِن شُبِّهَ لَهُمۡۚ وَإِنَّ ٱلَّذِينَ ٱخۡتَلَفُواْ فِيهِ لَفِي شَكّٖ مِّنۡهُۚ مَا لَهُم بِهِۦ مِنۡ عِلۡمٍ إِلَّا ٱتِّبَاعَ ٱلظَّنِّۚ وَمَا قَتَلُوهُ يَقِينَۢا ١٥٧","وقولهم إنا قتلنا المسيح عيسى ابن مريم رسول الله وما قتلوه وما صلبوه ولكن شبه لهم وإن الذين اختلفوا فيه لفي شك منه ما لهم به من علم إلا اتباع الظن وما قتلوه يقينا","އަދި، ހަމަކަށަވަރުން، ތިމަންމެން ﷲގެ ރަސޫލު، މަރިޔަމްގެފާނުންގެ ދަރިކަލުން އަލްމަސީޙު ޢީސާގެފާނު، ގަތުލު ކޮށްފީމުއޭ އެއުރެން ބުނުމުގެ ސަބަބުންމެއެވެ. އެއުރެން އެކަލޭގެފާނު ގަތުލެއް ނުކުރެއެވެ. އަދި، އެއުރެން އެކަލޭގެފާނު ޞަލީބަކަށްވެސް ނާރުވައެވެ. އެހެނެއްކަމަކު (އެއުރެން ގަތުލު ކޮށް ޞަލީބަށް އެރުވީ އެހެންމީހެކެވެ.) އެމީހާ، އެކަލޭގެފާނާ އެއްސިފަ ޖައްސަވާފައިވާތީ، އެއުރެންނަށް ފެނުނީއެވެ. ހަމަކަށަވަރުން، އެކަލޭގެފާނާމެދު ޚިލާފު ވީ މީހުންވަނީ، އެކަމާމެދު ޝައްކެއްގައިކަން ކަށަވަރެވެ. ހީޔަކަށް ތަބާ ވުން މެނުވީ، އެކަމާމެދު އެއުރެންނަކަށް އެނގުމެއްނެތެވެ. އަދި ހަމަ ޔަގީނުން، އެއުރެން އެކަލޭގެފާނު ގަތުލެއް ނުކުރެއެވެ.","",""],["₄ سورة النساء","158","بَل رَّفَعَهُ ٱللَّهُ إِلَيۡهِۚ وَكَانَ ٱللَّهُ عَزِيزًا حَكِيمٗا ١٥٨","بل رفعه الله إليه وكان الله عزيزا حكيما","އަދި ކިއެއްތަ! ﷲ، އެކަލާނގެ ހަޒުރަތަށް އެކަލޭގެފާނު އުފުއްލެވީއެވެ. ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","159","وَإِن مِّنۡ أَهۡلِ ٱلۡكِتَٰبِ إِلَّا لَيُؤۡمِنَنَّ بِهِۦ قَبۡلَ مَوۡتِهِۦۖ وَيَوۡمَ ٱلۡقِيَٰمَةِ يَكُونُ عَلَيۡهِمۡ شَهِيدٗا ١٥٩","وإن من أهل الكتاب إلا ليؤمنن به قبل موته ويوم القيامة يكون عليهم شهيدا","އެމީހަކު މަރުވުމުގެކުރިން (ނުވަތަ އެކަލޭގެފާނު އަވަހާރަވުމުގެ ކުރިން) އެކަލޭގެފާނަށް ހަމަކަށަވަރުންވެސް އީމާން ވާނެ މީހަކުކަމުގައި މެނުވީ، ފޮތުގެ އަހުލުވެރިންގެ ތެރެއިން އެކަކުވެސް ނުވެތެވެ. އަދި، ގިޔާމަތް ދުވަހުން އެއުރެންގެ މައްޗަށް ހެކިވަނިވި ބޭކަލަކު ކަމުގައި އެކަލޭގެފާނު ވާނެތެވެ.","",""],["₄ سورة النساء","160","فَبِظُلۡمٖ مِّنَ ٱلَّذِينَ هَادُواْ حَرَّمۡنَا عَلَيۡهِمۡ طَيِّبَٰتٍ أُحِلَّتۡ لَهُمۡ وَبِصَدِّهِمۡ عَن سَبِيلِ ٱللَّهِ كَثِيرٗا ١٦٠","فبظلم من الذين هادوا حرمنا عليهم طيبات أحلت لهم وبصدهم عن سبيل الله كثيرا","ޔަހޫދީން ކަމުގައިވީ މީހުންނަށް ހަލާލުކުރައްވާފައިވާ ރަނގަޅު ތަކެތި، އެއުރެންގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ހަރާމްކުރެއްވީ، އެއުރެން އަނިޔާވެރިވުމުގެ ސަބަބުންނެވެ. އަދި، އެއުރެން ﷲގެ މަގުގައި ގިނަގިނައިން ހުރަސްއަޅައި އުޅުމުގެ ސަބަބުންވެސް މެއެވެ.","",""],["₄ سورة النساء","161","وَأَخۡذِهِمُ ٱلرِّبَوٰاْ وَقَدۡ نُهُواْ عَنۡهُ وَأَكۡلِهِمۡ أَمۡوَٰلَ ٱلنَّاسِ بِٱلۡبَٰطِلِۚ وَأَعۡتَدۡنَا لِلۡكَٰفِرِينَ مِنۡهُمۡ عَذَابًا أَلِيمٗا ١٦١","وأخذهم الربا وقد نهوا عنه وأكلهم أموال الناس بالباطل وأعتدنا للكافرين منهم عذابا أليما","އަދި، އެއުރެންނަށް އެކަންތައް ނަހީކުރައްވާފައިވާ ޙާލުގައި، އެއުރެން ރިބާ ހިފިކަމުގެ ސަބަބުންނެވެ. އަދި، މީސްތަކުންގެ މުދާތައް ބާތިލު ގޮތުގައި އެއުރެން ކެއުމުގެ ސަބަބުންނެވެ. އެއުރެންގެ ތެރެއިން ކާފިރުކަމުގައި ދެމިތިބިމީހުންނަށް، ވޭންދެނިވި އަޒާބު ތިމަންރަސްކަލާނގެ ތައްޔާރުކުރެއްވީމެވެ.","",""],["₄ سورة النساء","162","لَّـٰكِنِ ٱلرَّـٰ‌سِخُونَ فِي ٱلۡعِلۡمِ مِنۡهُمۡ وَٱلۡمُؤۡمِنُونَ يُؤۡمِنُونَ بِمَآ أُنزِلَ إِلَيۡكَ وَمَآ أُنزِلَ مِن قَبۡلِكَۚ وَٱلۡمُقِيمِينَ ٱلصَّلَوٰةَۚ وَٱلۡمُؤۡتُونَ ٱلزَّكَوٰةَ وَٱلۡمُؤۡمِنُونَ بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِ أُوْلَـٰٓئِكَ سَنُؤۡتِيهِمۡ أَجۡرًا عَظِيمًا ١٦٢","لكن الراسخون في العلم منهم والمؤمنون يؤمنون بما أنزل إليك وما أنزل من قبلك والمقيمين الصلاة والمؤتون الزكاة والمؤمنون بالله واليوم الآخر أولئك سنؤتيهم أجرا عظيما","އެހެނެއްކަމަކު އެއުރެންގެތެރެއިން އިލްމުވެރިކަމުގައި ސާބިތުވެ ހަރުލައިތިބި މީހުންނާއި، މުއުމިނުން ކަލޭގެފާނަށް ބާވައިލެއްވި ފޮތަށާއި، ކަލޭގެފާނުގެ ކުރިން ބާވައިލެއްވި ފޮތްތަކަށް އީމާން ވެއެވެ. (އެއުރެންނާއި) އަދި ހާއްސަ ކޮށް ނަމާދު ގާއިމުކުރާ މީހުންނާއި، ޒަކާތް ދޭ މީހުންނާއި، ﷲއަށާއި، އާޚިރަތް ދުވަހަށް އީމާންވާ މީހުން (ދަންނާށެވެ!) އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ބޮޑުވެގެންވާ ދަރުމަ ދެއްވާހުށީމެވެ.","",""],["₄ سورة النساء","163","۞إِنَّآ أَوۡحَيۡنَآ إِلَيۡكَ كَمَآ أَوۡحَيۡنَآ إِلَىٰ نُوحٖ وَٱلنَّبِيِّـۧنَ مِنۢ بَعۡدِهِۦۚ وَأَوۡحَيۡنَآ إِلَىٰٓ إِبۡرَٰهِيمَ وَإِسۡمَٰعِيلَ وَإِسۡحَٰقَ وَيَعۡقُوبَ وَٱلۡأَسۡبَاطِ وَعِيسَىٰ وَأَيُّوبَ وَيُونُسَ وَهَٰرُونَ وَسُلَيۡمَٰنَۚ وَءَاتَيۡنَا دَاوُۥدَ زَبُورٗا ١٦٣","إنا أوحينا إليك كما أوحينا إلى نوح والنبيين من بعده وأوحينا إلى إبراهيم وإسماعيل وإسحاق ويعقوب والأسباط وعيسى وأيوب ويونس وهارون وسليمان وآتينا داوود زبورا","ނޫޙުގެފާނަށާއި، އެކަލޭގެފާނުގެ ފަހުން ތިއްބެވި ނަބީބޭކަލުންނަށް، ތިމަންރަސްކަލާނގެ ވަހީ އިއްވެވިފަދައިން، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށްވެސް ވަހީ އިއްވެވީމެވެ. އަދި، އިބްރާހީމްގެފާނަށާއި، އިސްމާޢީލުގެފާނަށާއި، އިސްޙާގުގެފާނަށާއި، ޔައުގޫބުގެފާނަށާއި، އެކަލޭގެފާނުންގެ އަސްބާޠުންނަށާއި، ޢީސާގެފާނަށާއި، އައްޔޫބުގެފާނަށާއި، ޔޫނުސްގެފާނަށާއި، ހާރޫނުގެފާނަށާއި، ސުލައިމާނުގެފާނަށްވެސް، ތިމަންރަސްކަލާނގެ ވަހީ އިއްވެވީމެވެ. އަދި، ދާވޫދުގެފާނަށް ތިމަންރަސްކަލާނގެ ޒަބޫރު ދެއްވީމެވެ.","",""],["₄ سورة النساء","164","وَرُسُلٗا قَدۡ قَصَصۡنَٰهُمۡ عَلَيۡكَ مِن قَبۡلُ وَرُسُلٗا لَّمۡ نَقۡصُصۡهُمۡ عَلَيۡكَۚ وَكَلَّمَ ٱللَّهُ مُوسَىٰ تَكۡلِيمٗا ١٦٤","ورسلا قد قصصناهم عليك من قبل ورسلا لم نقصصهم عليك وكلم الله موسى تكليما","ކުރިން އެ ރަސޫލުންގެ ވާހަކަ، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ކިޔައިދެއްވާފައިވާ ރަސޫލުންނާއި، ކަލޭގެފާނަށް އެ ރަސޫލުންގެ ވާހަކަ، ތިމަންރަސްކަލާނގެ ކިޔައިދެއްވާފައިނުވާ ރަސޫލުން، ތިމަންރަސްކަލާނގެ ފޮނުއްވީމެވެ. އަދި ބަސް ވަހީކުރެއްވުމަކުން މޫސާގެފާނަށް ﷲ ބަސް ވަހީކުރެއްވިއެވެ.","",""],["₄ سورة النساء","165","رُّسُلٗا مُّبَشِّرِينَ وَمُنذِرِينَ لِئَلَّا يَكُونَ لِلنَّاسِ عَلَى ٱللَّهِ حُجَّةُۢ بَعۡدَ ٱلرُّسُلِۚ وَكَانَ ٱللَّهُ عَزِيزًا حَكِيمٗا ١٦٥","رسلا مبشرين ومنذرين لئلا يكون للناس على الله حجة بعد الرسل وكان الله عزيزا حكيما","އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާ، އަދި އިންޒާރުކުރައްވާ ރަސޫލު ބޭކަލުންތަކެއް ފޮނުއްވީމެވެ. (އެއީ) ރަސޫލުން ފޮނުއްވުމަށްފަހު، ﷲގެ މައްޗަށް މީސްތަކުން ދައްކާނޭ ހުއްޖަތެއް ލިބިގެން ނުވުމަށްޓަކައެވެ. ޢަޒީޒުވަންތަ ޙަކީމްވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","166","لَّـٰكِنِ ٱللَّهُ يَشۡهَدُ بِمَآ أَنزَلَ إِلَيۡكَۖ أَنزَلَهُۥ بِعِلۡمِهِۦۖ وَٱلۡمَلَـٰٓئِكَةُ يَشۡهَدُونَۚ وَكَفَىٰ بِٱللَّهِ شَهِيدًا ١٦٦","لكن الله يشهد بما أنزل إليك أنزله بعلمه والملائكة يشهدون وكفى بالله شهيدا","އެހެނެއްކަމަކު ކަލޭގެފާނަށް، ﷲ ބާވައިލެއްވި ފޮތާމެދު ﷲ ހެކިވެވޮޑިގެންވެއެވެ. އެ ފޮތް ބާވައިލެއްވީ، އެކަލާނގެ ދެނެވޮޑިގަތުމާއެކުގައެވެ. އަދި މަލާއިކަތް ންވެސް (އެކަމަށް) ހެކިވެވަޑައިގަންނަވަތެވެ. ހެކިވެރިޔަކު ކަމުގައި ﷲ ފުދެއެވެ.","",""],["₄ سورة النساء","167","إِنَّ ٱلَّذِينَ كَفَرُواْ وَصَدُّواْ عَن سَبِيلِ ٱللَّهِ قَدۡ ضَلُّواْ ضَلَٰلَۢا بَعِيدًا ١٦٧","إن الذين كفروا وصدوا عن سبيل الله قد ضلوا ضلالا بعيدا","ހަމަކަށަވަރުން، ކާފިރުވެ، ﷲގެ މަގުން (މީސްތަކުން) އެއްކިބާކުޅަ މީހުން (ހައްގުގެ މަގުން) ދުރުވެގެންވާ މަގުފުރެދުމަކުން މަގުފުރެދިއްޖެކަން ކަށަވަރެވެ.","",""],["₄ سورة النساء","168","إِنَّ ٱلَّذِينَ كَفَرُواْ وَظَلَمُواْ لَمۡ يَكُنِ ٱللَّهُ لِيَغۡفِرَ لَهُمۡ وَلَا لِيَهۡدِيَهُمۡ طَرِيقًا ١٦٨","إن الذين كفروا وظلموا لم يكن الله ليغفر لهم ولا ليهديهم طريقا","ހަމަކަށަވަރުން، ކާފިރުވެ އަދި އަނިޔާވެރިވި މީހުންނަށް، ﷲ ފާފައެއް ނުފުއްސަވާނެތެވެ. އަދި، އެއްވެސް މަގަކަށް އެއުރެންނަށް އެކަލާނގެ މަގެއް ނުދައްކަވާނެތެވެ.","",""],["₄ سورة النساء","169","إِلَّا طَرِيقَ جَهَنَّمَ خَٰلِدِينَ فِيهَآ أَبَدٗاۚ وَكَانَ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٗا ١٦٩","إلا طريق جهنم خالدين فيها أبدا وكان ذلك على الله يسيرا","ނަރަކައިގެ މަގަށް މެނުވީއެވެ. އެއުރެން އެތާނގައި އަބަދަށް ދެމިތިބެނިވި ގޮތުގައެވެ. އެކަންތައް ﷲއަށް ދާދި ފަސޭހަކަމެއް ކަމުގައިވެއެވެ.","",""],["₄ سورة النساء","170","يَـٰٓأَيُّهَا ٱلنَّاسُ قَدۡ جَآءَكُمُ ٱلرَّسُولُ بِٱلۡحَقِّ مِن رَّبِّكُمۡ فَـَٔامِنُواْ خَيۡرٗا لَّكُمۡۚ وَإِن تَكۡفُرُواْ فَإِنَّ لِلَّهِ مَا فِي ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِۚ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمٗا ١٧٠","يا أيها الناس قد جاءكم الرسول بالحق من ربكم فآمنوا خيرا لكم وإن تكفروا فإن لله ما في السماوات والأرض وكان الله عليما حكيما","އޭ މީސްތަކުންނޭވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ހައްގު ދީނާއިގެން ރަސޫލާ ތިޔަބައިމީހުންގެ ގާތަށް ވަޑައިގެންފިއެވެ. ފަހެ، ތިޔަބައިމީހުން އީމާން ވާށެވެ! އެގޮތް ތިޔަބައިމީހުންނަށް ހެޔޮކަން ބޮޑެވެ. އަދި، ތިޔަބައިމީހުން ކާފިރު ވާނަމަ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އުޑުތަކާއި ބިމުގައިވާހައި ތަކެއްޗެއް މިލްކުވެގެންވަނީ ﷲއަށެވެ. މޮޅަށް ދެނެވޮޑިގެންވާ ޙަކީމްވަންތަ ކަލާނގެ ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["₄ سورة النساء","171","يَـٰٓأَهۡلَ ٱلۡكِتَٰبِ لَا تَغۡلُواْ فِي دِينِكُمۡ وَلَا تَقُولُواْ عَلَى ٱللَّهِ إِلَّا ٱلۡحَقَّۚ إِنَّمَا ٱلۡمَسِيحُ عِيسَى ٱبۡنُ مَرۡيَمَ رَسُولُ ٱللَّهِ وَكَلِمَتُهُۥٓ أَلۡقَىٰهَآ إِلَىٰ مَرۡيَمَ وَرُوحٞ مِّنۡهُۖ فَـَٔامِنُواْ بِٱللَّهِ وَرُسُلِهِۦۖ وَلَا تَقُولُواْ ثَلَٰثَةٌۚ ٱنتَهُواْ خَيۡرٗا لَّكُمۡۚ إِنَّمَا ٱللَّهُ إِلَٰهٞ وَٰحِدٞۖ سُبۡحَٰنَهُۥٓ أَن يَكُونَ لَهُۥ وَلَدٞۘ لَّهُۥ مَا فِي ٱلسَّمَٰوَٰتِ وَمَا فِي ٱلۡأَرۡضِۗ وَكَفَىٰ بِٱللَّهِ وَكِيلٗا ١٧١","يا أهل الكتاب لا تغلوا في دينكم ولا تقولوا على الله إلا الحق إنما المسيح عيسى ابن مريم رسول الله وكلمته ألقاها إلى مريم وروح منه فآمنوا بالله ورسله ولا تقولوا ثلاثة انتهوا خيرا لكم إنما الله إله واحد سبحانه أن يكون له ولد له ما في السماوات وما في الأرض وكفى بالله وكيلا","އޭ ފޮތުގެ އަހުލުވެރިންނޭވެ! ތިޔަބައިމީހުންގެ ދީނާމެދު ތިޔަބައިމީހުން ހައްދުފަހަނަޅައި ނުދާށެވެ! އަދި، ﷲއާމެދު ހައްގު ބަސްމެނުވީ، ތިޔަބައިމީހުން ނުބުނާށެވެ! މަރިޔަމްގެފާނުންގެ ދަރިކަލުން އަލްމަސީޙު ޢީސާގެފާނު ވާކަން ކަށަވަރީ، ﷲގެ ރަސޫލާ ކަމުގައެވެ. އަދި، އެކަލާނގެ ކަލިމަފުޅު ކަމުގައެވެ. އެ ކަލިމަފުޅު އެކަލާނގެ، މަރިޔަމްގެފާނާ ހަމަޔަށް ފޮނުއްވައި އެކަމަނާގައި، އެ ކަލިމަފުޅު ލެއްވިއެވެ. އަދި، އެކަލާނގެ ހަޒުރަތުން ލެއްވި ރޫޙު ފުޅެކެވެ. ފަހެ، ﷲއާއި، އެކަލާނގެ ރަސޫލުންނަށް ތިޔަބައިމީހުން އީމާން ވާށެވެ! އަދި، (އިލާހުން) ތިނެކޭ ތިޔަބައިމީހުން ނުބުނާހުށިކަމެވެ! އެ ބުނުން ތިޔަބައިމީހުން ހުއްޓައިލާށެވެ! އެގޮތް ތިޔަބައިމީހުންނަށް ހެޔޮކަން ބޮޑެވެ. ހަމަކަށަވަރުން، ﷲ ވާކަން ކަށަވަރީ އެއްކައުވަންތަ ކަލާނގެ ކަމުގައެވެ. އެކަލާނގެއަށް ދަރިކަލަކުވުމުން އެކަލާނގެ ހުސް ތާހިރު ވަންތައެވެ. އުޑުތަކުގައިވާހައި ތަކެއްޗާއި ބިމުގައި ވާހައި ތަކެތި، އެކަލާނގެއަށް މިލްކުވެގެންވެއެވެ. އަދި، ވަކީލަކު ކަމުގައި ﷲ ފުދެއެވެ.","",""],["₄ سورة النساء","172","لَّن يَسۡتَنكِفَ ٱلۡمَسِيحُ أَن يَكُونَ عَبۡدٗا لِّلَّهِ وَلَا ٱلۡمَلَـٰٓئِكَةُ ٱلۡمُقَرَّبُونَۚ وَمَن يَسۡتَنكِفۡ عَنۡ عِبَادَتِهِۦ وَيَسۡتَكۡبِرۡ فَسَيَحۡشُرُهُمۡ إِلَيۡهِ جَمِيعٗا ١٧٢","لن يستنكف المسيح أن يكون عبدا لله ولا الملائكة المقربون ومن يستنكف عن عبادته ويستكبر فسيحشرهم إليه جميعا","ﷲގެ އަޅަކަށް ވުމާމެދު ޢީސާގެފާނު ބޮޑާވެވަޑައެއް ނުގަނެއެވެ. އަދި، ކުއްތަން ކުރައްވާފައިވާ މަލާއިކަތް ންވެސް ﷲގެ އަޅުންނަށް ވުމާމެދު، ބޮޑާވެވަޑައެއް ނުގަނެއެވެ. އެކަލާނގެއަށް އަޅުކަން ކުރުމުން މަނާވެގަނެ، ކިބުރުވެރިވާ އެންމެން އެކުގައި، އެކަލާނގެ ހަޒުރަތަށް ގިޔާމަތް ދުވަހުން އެއްކުރައްވާނެތެވެ.","",""],["₄ سورة النساء","173","فَأَمَّا ٱلَّذِينَ ءَامَنُواْ وَعَمِلُواْ ٱلصَّـٰلِحَٰتِ فَيُوَفِّيهِمۡ أُجُورَهُمۡ وَيَزِيدُهُم مِّن فَضۡلِهِۦۖ وَأَمَّا ٱلَّذِينَ ٱسۡتَنكَفُواْ وَٱسۡتَكۡبَرُواْ فَيُعَذِّبُهُمۡ عَذَابًا أَلِيمٗا وَلَا يَجِدُونَ لَهُم مِّن دُونِ ٱللَّهِ وَلِيّٗا وَلَا نَصِيرٗا ١٧٣","فأما الذين آمنوا وعملوا الصالحات فيوفيهم أجورهم ويزيدهم من فضله وأما الذين استنكفوا واستكبروا فيعذبهم عذابا أليما ولا يجدون لهم من دون الله وليا ولا نصيرا","ފަހެ، އީމާންވެ، ސާލިހު ޢަމަލުކުޅަމީހުން ދަންނާށެވެ! ފަހެ، އެއުރެންގެ އުޖޫރަ އެއުރެންނަށް ހަމަޔަށް އެކަލާނގެ ފުއްދަވައި ދެއްވާނެތެވެ. އަދި، އެކަލާނގެ ފަޟްލު ވަންތަކަމުގެ ތެރެއިން، އެއުރެންނަށް އިތުރުކޮށްދެއްވާނެތެވެ. އަދި، ކިބުރުވެރިވެ، ބޮޑާވެގަތްމީހުން ދަންނާށެވެ! ފަހެ، ވޭންދެނިވި އަޒާބުން އެކަލާނގެ އެއުރެންނަށް އަޒާބު ދެއްވާނެތެވެ. އަދި، ﷲ ފިޔަވައި އެހީތެރިޔަކުވެސް، އަދި ނަސްރުވެރިޔަކުވެސް، އެއުރެންނަކަށް ނުފެންނާނެތެވެ.","",""],["₄ سورة النساء","174","يَـٰٓأَيُّهَا ٱلنَّاسُ قَدۡ جَآءَكُم بُرۡهَٰنٞ مِّن رَّبِّكُمۡ وَأَنزَلۡنَآ إِلَيۡكُمۡ نُورٗا مُّبِينٗا ١٧٤","يا أيها الناس قد جاءكم برهان من ربكم وأنزلنا إليكم نورا مبينا","އޭމީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ހުއްޖަތެއް، ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ގާތަށް އަތުވެއްޖެއެވެ. އަދި، ފާޅުވެ ބަޔާން ވެގެންވާ ނޫރެއް ތިޔަބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ ބާވައިލެއްވީމެވެ.","",""],["₄ سورة النساء","175","فَأَمَّا ٱلَّذِينَ ءَامَنُواْ بِٱللَّهِ وَٱعۡتَصَمُواْ بِهِۦ فَسَيُدۡخِلُهُمۡ فِي رَحۡمَةٖ مِّنۡهُ وَفَضۡلٖ وَيَهۡدِيهِمۡ إِلَيۡهِ صِرَٰطٗا مُّسۡتَقِيمٗا ١٧٥","فأما الذين آمنوا بالله واعتصموا به فسيدخلهم في رحمة منه وفضل ويهديهم إليه صراطا مستقيما","ފަހެ، ﷲއަށް އީމާންވެ، އެކަލާނގެ ރައްކާތެރި ކަމުގައި ހިފަހައްޓައިގެން ތިބިމީހުން ދަންނާށެވެ! ފަހެ، އެކަލާނގެ ރަހުމަތާއި ފަޟްލު ވަންތަކަމުގެ ތެރެޔަށް އެއުރެން ވައްދަވާނެތެވެ. އަދި، އެ މަގަށް ދިއުމަށް ސީދާވެގެންވާ ތެދުމަގެއް އެއުރެންނަށް އެކަލާނގެ ދައްކަވާނެތެވެ.","",""],["₄ سورة النساء","176","يَسۡتَفۡتُونَكَ قُلِ ٱللَّهُ يُفۡتِيكُمۡ فِي ٱلۡكَلَٰلَةِۚ إِنِ ٱمۡرُؤٌاْ هَلَكَ لَيۡسَ لَهُۥ وَلَدٞ وَلَهُۥٓ أُخۡتٞ فَلَهَا نِصۡفُ مَا تَرَكَۚ وَهُوَ يَرِثُهَآ إِن لَّمۡ يَكُن لَّهَا وَلَدٞۚ فَإِن كَانَتَا ٱثۡنَتَيۡنِ فَلَهُمَا ٱلثُّلُثَانِ مِمَّا تَرَكَۚ وَإِن كَانُوٓاْ إِخۡوَةٗ رِّجَالٗا وَنِسَآءٗ فَلِلذَّكَرِ مِثۡلُ حَظِّ ٱلۡأُنثَيَيۡنِۗ يُبَيِّنُ ٱللَّهُ لَكُمۡ أَن تَضِلُّواْۗ وَٱللَّهُ بِكُلِّ شَيۡءٍ عَلِيمُۢ ١٧٦","يستفتونك قل الله يفتيكم في الكلالة إن امرؤ هلك ليس له ولد وله أخت فلها نصف ما ترك وهو يرثها إن لم يكن لها ولد فإن كانتا اثنتين فلهما الثلثان مما ترك وإن كانوا إخوة رجالا ونساء فللذكر مثل حظ الأنثيين يبين الله لكم أن تضلوا والله بكل شيء عليم","(ކަލާލަތާމެދު) ކަލޭގެފާނުގެ އަރިހުން، އެއުރެން ފަތުވާއަށް އެދި ދަންނަވަތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ކަލާލަތާމެދު (އެބަހީ: އަޞްލެއް ފަރުޢެއް ނެތި މަރުވާމީހާގެ ތަރިކަޔާމެދު) ﷲ ތިޔަބައިމީހުންނަށް ބަޔާން ކޮށް ދެއްވަތެވެ. އެމީހަކަށް ދަރިޔަކު (ނުވަތަ ބަފަޔަކު) ނެތި، އަދި އެމީހަކަށް (އެއްބަނޑު އެއްބަފާ ނުވަތަ އެއްބަފާ) އުޚްތަކުވާ ޙާލު، މީހަކު މަރުވެއްޖެނަމަ، ފަހެ، އެމީހާ ދޫކުޅަ މުދަލުގެ ދެބައިކުޅައެއްބައި، އެ އުޚްތަށެވެ. އަދި، އެ އުޚްތަށް ދަރިޔަކު ނުވާނަމަ، އެމީހާ އެ އުޚްތު ވާރުތަކުރާނެއެވެ. (މަރުވިމީހާގެ ވާރިޘުންނަށް ތިބި) ދެ އުޚްތުން ކަމުގައިވާނަމަ، ފަހެ، އެ ދެ އުޚްތުންނަށް (އެ އަޚު) ދޫކުޅަ މުދަލުގެ ތިންބައިކުޅަ ދެބަޔެވެ. (ވާރިޘުންނަށް ތިބީ) އަންހެން ފިރިހެން، އެއްބަނޑު އެއްބަފާ ބަޔަކު ކަމުގައިވާނަމަ، ދެ އަންހެނުންގެ ބައިފަދަ ބަޔެއް ފިރިހެނަކަށެވެ. ތިޔަބައިމީހުންނަށް މަގު އޮޅިދާނެކަމަށްޓަކައި، ތިޔަބައިމީހުންނަށް ﷲ، ބަޔާން ކޮށް ދެއްވަތެވެ. ﷲއީ، ކޮންމެކަމެއްމެ، މޮޅަށްދެނެވޮޑިވެގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","1","بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ\n<br><br>\nيَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ أَوۡفُواْ بِٱلۡعُقُودِۚ أُحِلَّتۡ لَكُم بَهِيمَةُ ٱلۡأَنۡعَٰمِ إِلَّا مَا يُتۡلَىٰ عَلَيۡكُمۡ غَيۡرَ مُحِلِّي ٱلصَّيۡدِ وَأَنتُمۡ حُرُمٌۗ إِنَّ ٱللَّهَ يَحۡكُمُ مَا يُرِيدُ ١","بسم الله الرحمن الرحيم يا أيها الذين آمنوا أوفوا بالعقود أحلت لكم بهيمة الأنعام إلا ما يتلى عليكم غير محلي الصيد وأنتم حرم إن الله يحكم ما يريد","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން، އަގުދުތައް ފުއްދާށެވެ! އަދި، ތިޔަބައިމީހުންނަށް (އެތަކެއްޗާމެދު ހުކުމް އޮތްގޮތް ގުރްއާނުން) ބަޔާންކޮށްދެއްވާ ތަކެތި މެނުވީ، ނަޢަމް ސޫފިތައް، ތިޔަބައިމީހުންނަށް ހަލާލުކުރައްވާފައިވެއެވެ. ތިޔަބައިމީހުން އިހްރާމް ބަނދެގެންތިބެ، ޝިކާރަކުރުން ހުއްދަ ނުކުރާގޮތުގައެވެ. ހަމަކަށަވަރުން، ﷲ، އެކަލާނގެ އިރާދަކުރައްވާގޮތަށް ހުކުމްކުރައްވަތެވެ.","",""],["₅ سورة المائدة","2","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تُحِلُّواْ شَعَـٰٓئِرَ ٱللَّهِ وَلَا ٱلشَّهۡرَ ٱلۡحَرَامَ وَلَا ٱلۡهَدۡيَ وَلَا ٱلۡقَلَـٰٓئِدَ وَلَآ ءَآمِّينَ ٱلۡبَيۡتَ ٱلۡحَرَامَ يَبۡتَغُونَ فَضۡلٗا مِّن رَّبِّهِمۡ وَرِضۡوَٰنٗاۚ وَإِذَا حَلَلۡتُمۡ فَٱصۡطَادُواْۚ وَلَا يَجۡرِمَنَّكُمۡ شَنَـَٔانُ قَوۡمٍ أَن صَدُّوكُمۡ عَنِ ٱلۡمَسۡجِدِ ٱلۡحَرَامِ أَن تَعۡتَدُواْۘ وَتَعَاوَنُواْ عَلَى ٱلۡبِرِّ وَٱلتَّقۡوَىٰۖ وَلَا تَعَاوَنُواْ عَلَى ٱلۡإِثۡمِ وَٱلۡعُدۡوَٰنِۚ وَٱتَّقُواْ ٱللَّهَۖ إِنَّ ٱللَّهَ شَدِيدُ ٱلۡعِقَابِ ٢","يا أيها الذين آمنوا لا تحلوا شعائر الله ولا الشهر الحرام ولا الهدي ولا القلائد ولا آمين البيت الحرام يبتغون فضلا من ربهم ورضوانا وإذا حللتم فاصطادوا ولا يجرمنكم شنآن قوم أن صدوكم عن المسجد الحرام أن تعتدوا وتعاونوا على البر والتقوى ولا تعاونوا على الإثم والعدوان واتقوا الله إن الله شديد العقاب","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ﷲގެ ޝަޢާއިރު ތަކާއި، އަދި ހުރުމަތް ތެރި މައްސަރާއި، އަދި ގެފުޅަށް ހަދިޔާކުރާ ތަކެއްޗާއި، ގިލަފަތި އެލުވާފައިވާ ތަކެއްޗާއި، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ފަޟްލު ވަންތަކަމާއި، ރުއްސެވުންއެދި، ހުރުމަތް ތެރިވެގެންވާ ގެފުޅަށް ގަސްދު ކޮށްގެން އަންނަމީހުންގެ ހުރުމަތް ނުކަނޑާށެވެ! (މުރާދަކީ ހައްޖުގެ އަޅުކަން ކުރުމަށް ކަނޑައެޅިގެންވާ ތަންތަނާއި، ކުރެވޭ އަޅުކަމަށް ހުރުމަތް ތެރިކޮށްހިތައި، އެކަމުގެ ތެރޭގައި ކުރުން މަނާކުރައްވާފައިވާ ކަންތައްތައް ހުއްދަ ނުކުރާށެވެ! އަދި ހުރުމަތް ތެރި މައްސަރުތަކުގައި މަނާކުރައްވާފައިވާ ހަނގުރާމަ ކުރުންފަދަ ކަންތައްތައް ހުއްދަ ނުކުރާށެވެ! ހަމައެފަދައިން، ގެފުޅަށް ހަދިޔާކުރާ ގެރި، ބަކަރި، ޖަމަލާއި، އެ ހަދިޔާކުރާ ތަކެތި، ފާހަގަކުރުމުގެ ގޮތުން ކަރުގައި ގިލަފަތި އަޅުވާފައިވާ ތަކެއްޗާއި، އަދި އެނޫންވެސް ތަކެތި އަތުލައި، އެ ތަކެއްޗަށް ގެއްލުންދިނުން ހުއްދަ ނުކުރާށެވެ! އަދި ގެފުޅަށް ދިޔުން ގަސްދު ކޮށްގެންދާ މީހުންގެ މަގުގައި ހުރަސްއަޅައި ގެއްލުންދީހެދުން ހުއްދަ ނުކުރާށެވެ!) ތިޔަބައިމީހުން އިހްރާމް ކަނޑައިފި ހިނދެއްގައި، ތިޔަބައިމީހުން ޝިކާރަކުރާށެވެ! އަދި ތިޔަބައިމީހުން ހުރުމަތް ތެރިވެގެންވާ މިސްކިތަށް (އެބަހީ: كعبةﷲގެފުޅަށް) ތިޔަބައިމީހުން ދިޔަނުދީ ހުރަސްއެޅިކަމަށްޓަކައި، ބަޔަކުމީހުންގެ މައްޗަށް ތިޔަބައިމީހުންގައި އުފެދުނު ނުރުހުންތެރިކަމެއް އެއީ، އެހެންމީހުންގެ މައްޗަށް ނަހަމައިން ތިޔަބައިމީހުން ހައްދުފަހަނަޅައިދިޔުމުގެ ސަބަބެއްކަމުގައި މެދުވެރި ނުކުރާށެވެ! އަދި ހެޔޮކަންތައް ކުޅައުމާއި، ތަގުވާވެރިވުމުގެ މައްޗަށް ތިޔަބައިމީހުން އެކަކު އަނެކަކަށް އެހީވެ، ވާގިވެރިވާށެވެ! އަދި ފާފަވެރިވުމާއި އަދާވަތް ތެރިވުމުގެ މައްޗަށް، ތިޔަބައިމީހުން އެކަކު އަނެކަކަށް އެހީވެ، ވާގިވެރި ނުވާށެވެ! އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! ހަމަކަށަވަރުން، ﷲއީ އުގޫބާތް ގަދަފަދަ ވެގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","3","حُرِّمَتۡ عَلَيۡكُمُ ٱلۡمَيۡتَةُ وَٱلدَّمُ وَلَحۡمُ ٱلۡخِنزِيرِ وَمَآ أُهِلَّ لِغَيۡرِ ٱللَّهِ بِهِۦ وَٱلۡمُنۡخَنِقَةُ وَٱلۡمَوۡقُوذَةُ وَٱلۡمُتَرَدِّيَةُ وَٱلنَّطِيحَةُ وَمَآ أَكَلَ ٱلسَّبُعُ إِلَّا مَا ذَكَّيۡتُمۡ وَمَا ذُبِحَ عَلَى ٱلنُّصُبِ وَأَن تَسۡتَقۡسِمُواْ بِٱلۡأَزۡلَٰمِۚ ذَٰلِكُمۡ فِسۡقٌۗ ٱلۡيَوۡمَ يَئِسَ ٱلَّذِينَ كَفَرُواْ مِن دِينِكُمۡ فَلَا تَخۡشَوۡهُمۡ وَٱخۡشَوۡنِۚ ٱلۡيَوۡمَ أَكۡمَلۡتُ لَكُمۡ دِينَكُمۡ وَأَتۡمَمۡتُ عَلَيۡكُمۡ نِعۡمَتِي وَرَضِيتُ لَكُمُ ٱلۡإِسۡلَٰمَ دِينٗاۚ فَمَنِ ٱضۡطُرَّ فِي مَخۡمَصَةٍ غَيۡرَ مُتَجَانِفٖ لِّإِثۡمٖ فَإِنَّ ٱللَّهَ غَفُورٞ رَّحِيمٞ ٣","حرمت عليكم الميتة والدم ولحم الخنزير وما أهل لغير الله به والمنخنقة والموقوذة والمتردية والنطيحة وما أكل السبع إلا ما ذكيتم وما ذبح على النصب وأن تستقسموا بالأزلام ذلكم فسق اليوم يئس الذين كفروا من دينكم فلا تخشوهم واخشون اليوم أكملت لكم دينكم وأتممت عليكم نعمتي ورضيت لكم الإسلام دينا فمن اضطر في مخمصة غير متجانف لإثم فإن الله غفور رحيم","މުޅަތަކެއްޗާއި، (އޮހޮރޭ) ލެޔާއި، އޫރުމަހާއި، ﷲ ނޫން އެހެން ފަރާތެއްގެ ނަންގަނެ ކަތިލާ ތަކެއްޗާއި، ކަރުގައި ހިފައިގެން މަރައިލާ ތަކެއްޗާއި، ޖަހައި މަރައިލާ ތަކެއްޗާއި، އުސްތަނަކުން ވެއްޓި މަރުވާ ތަކެއްޗާއި، (އެހެން ޖަނަވާރެއްގެ) ދަޅުންޖަހައިގެން މަރުވާތަކެއްޗާއި، މިނިކާ ޖަނަވާރެއް (އެއްބައި) ކައިފައިވާ ތަކެތި، ތިޔަބައިމީހުންގެ މައްޗަށް ހަރާމްކުރައްވާފައިވެއެވެ. (މިތަކެތީގެ ތެރެއިން ފުރާނަހުއްޓައި އެއެއްޗެއް އަތުޖެހި ޝަރުއީ ހަމައިގެ މަތިން) ތިޔަބައިމީހުން ކަތިލި އެއްޗެއް މެނުވީއެވެ. އަދި ބުދުތަކުގެ ނަންމައްޗަށް ކަތިލާ ތަކެއްޗާއި، އަޒްލާމް މެދުވެރިކޮށްގެން ތިޔަބައިމީހުންގެ ނަސީބު ހުރިގޮތާއި، ކަންތަކުގެ ރަނގަޅުގޮތް ބަލައިހެދުންވެސް، ތިޔަބައިމީހުންގެ މައްޗަށް ހަރާމްކުރައްވާފައިވެއެވެ. ފަހެ، އެކަންތައްތަކަކީ، ފާސިގު ކަންތައްތަކެކެވެ. މިއަދު، ތިޔަބައިމީހުންގެ ދީނާމެދު (އެބަހީ: އެ ދީނަށް ގެއްލުމެއް ދެވިދާނެ ކަމާމެދު) ކާފިރުން، ނާއުއްމީދު ވެއްޖެއެވެ. ފަހެ، އެއުރެންދެކެ ތިޔަބައިމީހުން ބިރު ނުގަންނާށެވެ! އަދި ތިމަންރަސްކަލާނގެއަށް ތިޔަބައިމީހުން ބިރުވެތިވާށެވެ! މިއަދު، ތިޔަބައިމީހުންގެ ދީން، ތިޔަބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ ފުރިހަމަކޮށްދެއްވައިފީމެވެ. އަދި ތިމަންރަސްކަލާނގެ ނިއުމަތް، ތިޔަބައިމީހުންގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ފުރިހަމަކޮށްދެއްވައިފީމެވެ. އަދި އިސްލާމް ދީން ތިޔަބައިމީހުންނަށް ދީނެއްކަމުގައި، ތިމަންރަސްކަލާނގެ ރުހިވޮޑިގެންފީމެވެ. ފަހެ، ބަނޑުހައިހޫނުކަމެއްގެ ތެރޭގައި ފާފައިގެ ފަރާތަށް ލެނބިގަތުމެއްނެތި (އިސްވެދިޔަ ހަރާމް ތަކެތީގެ ތެރެއިން އެއްޗެއް ކެއުމަށް) މަޖުބޫރުވީ މީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ. (ނޯޓު: އަޒްލާމަކީ، ފާލުބެލުމަށް ޖާހިލީ ޒަމާނުގައި ބޭނުންކޮށްއުޅޭ ދަނޑިކޮޅުތަކެކެވެ. ނުވަތަ ދުނިދަނޑިތަކެކެވެ.)","",""],["₅ سورة المائدة","4","يَسۡـَٔلُونَكَ مَاذَآ أُحِلَّ لَهُمۡۖ قُلۡ أُحِلَّ لَكُمُ ٱلطَّيِّبَٰتُ وَمَا عَلَّمۡتُم مِّنَ ٱلۡجَوَارِحِ مُكَلِّبِينَ تُعَلِّمُونَهُنَّ مِمَّا عَلَّمَكُمُ ٱللَّهُۖ فَكُلُواْ مِمَّآ أَمۡسَكۡنَ عَلَيۡكُمۡ وَٱذۡكُرُواْ ٱسۡمَ ٱللَّهِ عَلَيۡهِۖ وَٱتَّقُواْ ٱللَّهَۚ إِنَّ ٱللَّهَ سَرِيعُ ٱلۡحِسَابِ ٤","يسألونك ماذا أحل لهم قل أحل لكم الطيبات وما علمتم من الجوارح مكلبين تعلمونهن مما علمكم الله فكلوا مما أمسكن عليكم واذكروا اسم الله عليه واتقوا الله إن الله سريع الحساب","އެއުރެންނަށް ހަލާލުކުރެއްވީ، ކޮން އެއްޗެއްތޯ ކަލޭގެފާނާ އެއުރެން ސުވާލުކުރެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ރަނގަޅު ތަކެތި ތިޔަބައިމީހުންނަށް ހަލާލުކުރެއްވިއެވެ. އަދި ޝިކާރަކުރާ ޖަނަވާރާއި، ދޫނީގެ ތެރެއިން ޝިކާރަކުރުމަށް އެ ތަކެއްޗަށް ތިޔަބައިމީހުން އުނގަންނައިދޭ ޙާލު، ތިޔަބައިމީހުން އުނގަންނައިދިން ޖަނަވާރާއި، ދޫނީގެ ޝިކާރަ ހަލާލުކުރެއްވިއެވެ. ﷲ ތިޔަބައިމީހުންނަށް އުނގަންނައި ދެއްވި ކަންތަކުގެ ތެރެއިން އެ ތަކެއްޗަށް، ތިޔަބައިމީހުން އުނގަންނައިދެމުއެވެ. ފަހެ، އެތަކެތި ތިޔަބައިމީހުންނަށް ހިފައިގެން ގެނެސްދޭ ތަކެތީގެ ތެރެއިން ތިޔަބައިމީހުން ކާށެވެ! އަދި އެ ޝިކާރައިގެ މައްޗަށް ﷲގެ އިސްމުފުޅު ތިޔަބައިމީހުން ކިޔާށެވެ! އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ހިސާބު ބެއްލެވުން އަވަސްވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","5","ٱلۡيَوۡمَ أُحِلَّ لَكُمُ ٱلطَّيِّبَٰتُۖ وَطَعَامُ ٱلَّذِينَ أُوتُواْ ٱلۡكِتَٰبَ حِلّٞ لَّكُمۡ وَطَعَامُكُمۡ حِلّٞ لَّهُمۡۖ وَٱلۡمُحۡصَنَٰتُ مِنَ ٱلۡمُؤۡمِنَٰتِ وَٱلۡمُحۡصَنَٰتُ مِنَ ٱلَّذِينَ أُوتُواْ ٱلۡكِتَٰبَ مِن قَبۡلِكُمۡ إِذَآ ءَاتَيۡتُمُوهُنَّ أُجُورَهُنَّ مُحۡصِنِينَ غَيۡرَ مُسَٰفِحِينَ وَلَا مُتَّخِذِيٓ أَخۡدَانٖۗ وَمَن يَكۡفُرۡ بِٱلۡإِيمَٰنِ فَقَدۡ حَبِطَ عَمَلُهُۥ وَهُوَ فِي ٱلۡأٓخِرَةِ مِنَ ٱلۡخَٰسِرِينَ ٥","اليوم أحل لكم الطيبات وطعام الذين أوتوا الكتاب حل لكم وطعامكم حل لهم والمحصنات من المؤمنات والمحصنات من الذين أوتوا الكتاب من قبلكم إذا آتيتموهن أجورهن محصنين غير مسافحين ولا متخذي أخدان ومن يكفر بالإيمان فقد حبط عمله وهو في الآخرة من الخاسرين","މިއަދު ތިޔަބައިމީހުންނަށް ރަނގަޅު ތަކެތި ހަލާލުކުރައްވައިފިއެވެ. އަދި ފޮތް ލިބުނު މީހުންގެ ކާނާވެސް ތިޔަބައިމީހުންނަށް ހަލާލު ވެގެންވެއެވެ. އަދި ތިޔަބައިމީހުންގެ ކާނާ އެއުރެންނަށް ހަލާލު ވެގެންވެއެވެ. ޢިއްފަތް ތެރި މުއުމިނު އަންހެނުންނާއި، ތިޔަބައިމީހުންގެ ކުރިން ފޮތް ލިބުނު މީހުންގެ ތެރެއިން މިނިވަން އަންހެނުން ތިޔަބައިމީހުންނަށް ހަލާލު ވެގެންވެއެވެ. އެކަނބަލުންގެ ރަން ތިޔަބައިމީހުން އެކަނބަލުންނަށް ދީފިނަމައެވެ. ކާވެނީގެ ޢިއްފަތް ތެރިކަން ހޯދާބަޔެއްގެ ގޮތުގައެވެ. ޒިނޭކުރާ ބަޔެއްގެ ގޮތުގައެއް ނޫނެވެ. ސިއްރުން ޒިނޭކުރާ އެކުވެރި އަންހެނުން ގެންގުޅޭ ބަޔެއްގެ ގޮތުގައެއްވެސް ނޫނެވެ. އަދި އީމާންކަމަށް ކާފިރު ވާމީހާ (އެބަހީ: އިސްލާމް ދީންގެ ހުކުމްތަކަށް ދެކޮޅު ހަދާމީހާ ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އެމީހާގެ ޢަމަލު ބާތިލު ވެގެންވެއެވެ. އަދި އޭނާވަނީ އާޚިރަތުގައި ގެއްލެނިވެގެންވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["₅ سورة المائدة","6","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ إِذَا قُمۡتُمۡ إِلَى ٱلصَّلَوٰةِ فَٱغۡسِلُواْ وُجُوهَكُمۡ وَأَيۡدِيَكُمۡ إِلَى ٱلۡمَرَافِقِ وَٱمۡسَحُواْ بِرُءُوسِكُمۡ وَأَرۡجُلَكُمۡ إِلَى ٱلۡكَعۡبَيۡنِۚ وَإِن كُنتُمۡ جُنُبٗا فَٱطَّهَّرُواْۚ وَإِن كُنتُم مَّرۡضَىٰٓ أَوۡ عَلَىٰ سَفَرٍ أَوۡ جَآءَ أَحَدٞ مِّنكُم مِّنَ ٱلۡغَآئِطِ أَوۡ لَٰمَسۡتُمُ ٱلنِّسَآءَ فَلَمۡ تَجِدُواْ مَآءٗ فَتَيَمَّمُواْ صَعِيدٗا طَيِّبٗا فَٱمۡسَحُواْ بِوُجُوهِكُمۡ وَأَيۡدِيكُم مِّنۡهُۚ مَا يُرِيدُ ٱللَّهُ لِيَجۡعَلَ عَلَيۡكُم مِّنۡ حَرَجٖ وَلَٰكِن يُرِيدُ لِيُطَهِّرَكُمۡ وَلِيُتِمَّ نِعۡمَتَهُۥ عَلَيۡكُمۡ لَعَلَّكُمۡ تَشۡكُرُونَ ٦","يا أيها الذين آمنوا إذا قمتم إلى الصلاة فاغسلوا وجوهكم وأيديكم إلى المرافق وامسحوا برءوسكم وأرجلكم إلى الكعبين وإن كنتم جنبا فاطهروا وإن كنتم مرضى أو على سفر أو جاء أحد منكم من الغائط أو لامستم النساء فلم تجدوا ماء فتيمموا صعيدا طيبا فامسحوا بوجوهكم وأيديكم منه ما يريد الله ليجعل عليكم من حرج ولكن يريد ليطهركم وليتم نعمته عليكم لعلكم تشكرون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ނަމާދަށް ތެދުވެއްޖެނަމަ، (އެބަހީ: ނަމާދުކުރާން ގަސްދު ކޮށްފިނަމަ) ފަހެ، ތިޔަބައިމީހުންގެ މޫނުތަކާއި، ތިޔަބައިމީހުންގެ އަތްތައް، އުޅަނބޮށިތަކާ ހަމަޔަށް ދޮންނާށެވެ! އަދި ތިޔަބައިމީހުންގެ ބޯތަކުގައި (ފެން) ފުހޭށެވެ! އަދި ތިޔަބައިމީހުންގެ ފައިތައް ދެތަނބިކަށްޓާހަމަޔަށް ދޮންނާށެވެ! އަދި ޖުނުބުވެރިން ކަމުގައި ތިޔަބައިމީހުން ވެއްޖެނަމަ، ފަހެ، ތިޔަބައިމީހުން ތާހިރު ވެގަންނާށެވެ! އަދި ތިޔަބައިމީހުންނީ ބަލިމީހުން ކަމުގައި ވެއްޖެނަމަ، ނުވަތަ ދަތުރެއްގެ މަތީގައި ވެއްޖެނަމަ، ނުވަތަ ތިޔަބައިމީހުންކުރެ މީހަކު ހަނޑަހުން އަތުވެއްޖެނަމަ، ނުވަތަ އަންހެނުންގައި ބީހިއްޖެނަމަ، ދެން، ފެން ނުލިބިއްޖިއްޔާ ތާހިރު ވެލީން ތިޔަބައިމީހުން ތަޔައްމަމުކުރާށެވެ! ފަހެ، ތިޔަބައިމީހުންގެ މޫނުތަކާއި، އަތްތަކުގައި އެ ވެލީން ފުހޭށެވެ! ތިޔަބައިމީހުންގެ މައްޗަށް ދަތިކަމެއް ލެއްވުމަކަށް ﷲ އިރާދައެއް ނުކުރައްވަތެވެ. އެހެނެއްކަމަކު އެކަލާނގެ އިރާދަކުރައްވަނީ ތިޔަބައިމީހުން ތާހިރުކުރެއްވުމަށާއި، ތިޔަބައިމީހުންގެ މައްޗަށް އެކަލާނގެ ނިއުމަތް ފުރިހަމަ ކުރެއްވުމަށެވެ. (އެއީ) ތިޔަބައިމީހުން ޝުކުރުކުޅައުމަށްޓަކައެވެ.","",""],["₅ سورة المائدة","7","وَٱذۡكُرُواْ نِعۡمَةَ ٱللَّهِ عَلَيۡكُمۡ وَمِيثَٰقَهُ ٱلَّذِي وَاثَقَكُم بِهِۦٓ إِذۡ قُلۡتُمۡ سَمِعۡنَا وَأَطَعۡنَاۖ وَٱتَّقُواْ ٱللَّهَۚ إِنَّ ٱللَّهَ عَلِيمُۢ بِذَاتِ ٱلصُّدُورِ ٧","واذكروا نعمة الله عليكم وميثاقه الذي واثقكم به إذ قلتم سمعنا وأطعنا واتقوا الله إن الله عليم بذات الصدور","ތިމަންމެން އަހައި ކިޔަމަންވެއްޖައީމުއޭ ތިޔަބައިމީހުން ބުނިހިނދު، ތިޔަބައިމީހުންނަށް ﷲ ދެއްވާފައިވާ ނިއުމަތާއި، ތިޔަބައިމީހުންގެ ކިބައިން އެކަލާނގެ ހިއްޕަވާފައިވާ އަހުދު ކަށަވަރު ތިޔަބައިމީހުން ހަނދުމަކުރާށެވެ! އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ހިތްތަކުގައިވާހާ ކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","8","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ كُونُواْ قَوَّـٰ‌مِينَ لِلَّهِ شُهَدَآءَ بِٱلۡقِسۡطِۖ وَلَا يَجۡرِمَنَّكُمۡ شَنَـَٔانُ قَوۡمٍ عَلَىٰٓ أَلَّا تَعۡدِلُواْۚ ٱعۡدِلُواْ هُوَ أَقۡرَبُ لِلتَّقۡوَىٰۖ وَٱتَّقُواْ ٱللَّهَۚ إِنَّ ٱللَّهَ خَبِيرُۢ بِمَا تَعۡمَلُونَ ٨","يا أيها الذين آمنوا كونوا قوامين لله شهداء بالقسط ولا يجرمنكم شنآن قوم على ألا تعدلوا اعدلوا هو أقرب للتقوى واتقوا الله إن الله خبير بما تعملون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ﷲއަށްޓަކައި އެކަލާނގެ ހައްގުތައް ފުރިހަމަޔަށް ގާއިމުކުރާ، އަދި ޢަދުލަށް ހެކިދޭ ބަޔަކު ކަމުގައިވާށެވެ! އަދި ބަޔަކުމީހުންދެކެ ތިޔަބައިމީހުންގައި އުފެދިފައިވާ ރުޅިވެރިކަމެއް އެއީ، ތިޔަބައިމީހުން ޢަދުލުވެރި ނުވުމުގެ މައްޗަށް ބާރުއަޅާކަމެއް ކަމުގައި ނަހަދާށެވެ! ތިޔަބައިމީހުން ޢަދުލުވެރިވާށެވެ! އެގޮތް ތަގުވާވެރިކަމާ ގާތްކަން ބޮޑެވެ. އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ތިޔަބައިމީހުންކުރާ ޢަމަލުތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","9","وَعَدَ ٱللَّهُ ٱلَّذِينَ ءَامَنُواْ وَعَمِلُواْ ٱلصَّـٰلِحَٰتِ لَهُم مَّغۡفِرَةٞ وَأَجۡرٌ عَظِيمٞ ٩","وعد الله الذين آمنوا وعملوا الصالحات لهم مغفرة وأجر عظيم","އީމާންވެ ސާލިހު ޢަމަލުކުޅަމީހުންނަށް ފާފަފުއްސެވުމާއި، ބޮޑުވެގެންވާ ދަރުމަހުރިކަމަށް އެއުރެންނަށް ﷲ ވައުދުކުރައްވާފައިވެއެވެ.","",""],["₅ سورة المائدة","10","وَٱلَّذِينَ كَفَرُواْ وَكَذَّبُواْ بِـَٔايَٰتِنَآ أُوْلَـٰٓئِكَ أَصۡحَٰبُ ٱلۡجَحِيمِ ١٠","والذين كفروا وكذبوا بآياتنا أولئك أصحاب الجحيم","އަދި ކާފިރުވެ ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުޅަމީހުން އެއީ، ނަރަކައިގެ އަހުލުވެރިންނެވެ.","",""],["₅ سورة المائدة","11","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ ٱذۡكُرُواْ نِعۡمَتَ ٱللَّهِ عَلَيۡكُمۡ إِذۡ هَمَّ قَوۡمٌ أَن يَبۡسُطُوٓاْ إِلَيۡكُمۡ أَيۡدِيَهُمۡ فَكَفَّ أَيۡدِيَهُمۡ عَنكُمۡۖ وَٱتَّقُواْ ٱللَّهَۚ وَعَلَى ٱللَّهِ فَلۡيَتَوَكَّلِ ٱلۡمُؤۡمِنُونَ ١١","يا أيها الذين آمنوا اذكروا نعمت الله عليكم إذ هم قوم أن يبسطوا إليكم أيديهم فكف أيديهم عنكم واتقوا الله وعلى الله فليتوكل المؤمنون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ބަޔަކުމީހުން (އަދާވަތް ތެރިވުމުގެގޮތުން) ތިޔަބައިމީހުން ނެތިކޮށްލުމަށްރާވައި، އެއުރެންގެ އަތްތަކުން މަސައްކަތް ކުރިހިނދު، ﷲ ތިޔަބައިމީހުންނަށް ދެއްވި ނިއުމަތް ހަނދުމަކުރާށެވެ! ފަހެ، އެކަލާނގެ ތިޔަބައިމީހުންގެ ކިބައިން އެއުރެންގެ އަތްތައް ދުރުކުރެއްވިއެވެ. އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! (ހަމައެކަނި) ﷲއަށް މުއުމިނުން ވަކީލުކުރާހުށިކަމެވެ!","",""],["₅ سورة المائدة","12","۞وَلَقَدۡ أَخَذَ ٱللَّهُ مِيثَٰقَ بَنِيٓ إِسۡرَـٰٓءِيلَ وَبَعَثۡنَا مِنۡهُمُ ٱثۡنَيۡ عَشَرَ نَقِيبٗاۖ وَقَالَ ٱللَّهُ إِنِّي مَعَكُمۡۖ لَئِنۡ أَقَمۡتُمُ ٱلصَّلَوٰةَ وَءَاتَيۡتُمُ ٱلزَّكَوٰةَ وَءَامَنتُم بِرُسُلِي وَعَزَّرۡتُمُوهُمۡ وَأَقۡرَضۡتُمُ ٱللَّهَ قَرۡضًا حَسَنٗا لَّأُكَفِّرَنَّ عَنكُمۡ سَيِّـَٔاتِكُمۡ وَلَأُدۡخِلَنَّكُمۡ جَنَّـٰتٖ تَجۡرِي مِن تَحۡتِهَا ٱلۡأَنۡهَٰرُۚ فَمَن كَفَرَ بَعۡدَ ذَٰلِكَ مِنكُمۡ فَقَدۡ ضَلَّ سَوَآءَ ٱلسَّبِيلِ ١٢","ولقد أخذ الله ميثاق بني إسرائيل وبعثنا منهم اثني عشر نقيبا وقال الله إني معكم لئن أقمتم الصلاة وآتيتم الزكاة وآمنتم برسلي وعزرتموهم وأقرضتم الله قرضا حسنا لأكفرن عنكم سيئاتكم ولأدخلنكم جنات تجري من تحتها الأنهار فمن كفر بعد ذلك منكم فقد ضل سواء السبيل","ހަމަކަށަވަރުން، ﷲ، އިސްރާއީލުގެދަރިންގެ ކިބައިން ކަށަވަރުވެގެންވާ އަހުދު ހިއްޕެވިއެވެ. އަދި އެއުރެންގެ ތެރެއިން ބާރަ ނަގީބުން (އެބަހީ: ބާރަ ވެރިން) ތިމަންރަސްކަލާނގެ އިޚްތިޔާރުކުރެއްވީމެވެ. އަދި ﷲ ވަހީކުރެއްވިއެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނާއެކު ވޮޑިގެންވަމެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ނަމާދު ގާއިމުކުރާނަމަ، އަދި ޒަކާތް ދޭނަމަ، އަދި ތިމަންރަސްކަލާނގެ ރަސޫލުންނަށް ތިޔަބައިމީހުން އީމާންވެ، އެ ރަސޫލުންނަށް ނަސްރު ދޭނަމަ، އަދި ﷲއަށްޓަކައި ހެޔޮވެގެންވާ ދަރަންޏަކުން ދަރަނިދޭނަމަ، (އެބަހީ: ﷲގެ މަގުގައި ހޭދަކުރާނަމަ) ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންގެ ފާފަތައް ފުއްސަވާހުށީމެވެ. އަދި އެތާނގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާހުންނަ ސުވަރުގެތަކަށް، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން ވައްދަވާހުށީމެވެ. ދެން އެ އެންގެވުމަށްފަހު، ތިޔަބައިމީހުންގެ ތެރެއިން ކާފިރު ވިމީހާ، ފަހެ، ހަމަމަގުން އެއްކިބާވެ ފުރެދިއްޖެކަން ކަށަވަރެވެ.","",""],["₅ سورة المائدة","13","فَبِمَا نَقۡضِهِم مِّيثَٰقَهُمۡ لَعَنَّـٰهُمۡ وَجَعَلۡنَا قُلُوبَهُمۡ قَٰسِيَةٗۖ يُحَرِّفُونَ ٱلۡكَلِمَ عَن مَّوَاضِعِهِۦ وَنَسُواْ حَظّٗا مِّمَّا ذُكِّرُواْ بِهِۦۚ وَلَا تَزَالُ تَطَّلِعُ عَلَىٰ خَآئِنَةٖ مِّنۡهُمۡ إِلَّا قَلِيلٗا مِّنۡهُمۡۖ فَٱعۡفُ عَنۡهُمۡ وَٱصۡفَحۡۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلۡمُحۡسِنِينَ ١٣","فبما نقضهم ميثاقهم لعناهم وجعلنا قلوبهم قاسية يحرفون الكلم عن مواضعه ونسوا حظا مما ذكروا به ولا تزال تطلع على خائنة منهم إلا قليلا منهم فاعف عنهم واصفح إن الله يحب المحسنين","ދެން އެއުރެންގެ ކަށަވަރުވެގެންވާ އަހުދެއުރެން އުވައިލުމުގެ ސަބަބުން، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ލައުނަތް ލެއްވީމެވެ. އަދި އެއުރެންގެ ހިތްތައް ހަރުކަށި ހިތްތަކެއްކަމުގައި ލެއްވީމެވެ. އެއުރެން (ތައުރާތު ގައިވާ) ކަލިމަފުޅުތައް އޮންނަންވީ ތަންތަނުން ބަދަލުކޮށް އޮޅުވާލައިހަދަތެވެ. އަދި އެއުރެންނަށް ހަނދާންކޮށްދެއްވި ކަންތަކުގެ ތެރެއިން ބަޔެއް (އެބަހީ: މުޙައްމަދުގެފާނަށް ތަބާ ވުމަށް ތައުރާތުގައި ކުރައްވާފައިވާ އަމުރުތައް) އެއުރެން ހަނދާން ނައްތައިލިއެވެ. އޭގެތެރެއިން މަދުބަޔެއްގެ ކިބައިން މެނުވީ، އެއުރެންގެ ތެރެއިން ޚިޔާނަތް ތެރިވުން ކަލޭގެފާނަށް އަބަދުވެސް ފެނިވަޑައިގަންނަވާނެތެވެ. ފަހެ، އެއުރެންނަށް ކަލޭގެފާނު އަފޫކުރައްވައި، މާފުކުރައްވާށެވެ! ހަމަކަށަވަރުން، އިހްސާން ތެރިންދެކެ ﷲ ލޯބިވެވޮޑިގެންވެތެވެ.","",""],["₅ سورة المائدة","14","وَمِنَ ٱلَّذِينَ قَالُوٓاْ إِنَّا نَصَٰرَىٰٓ أَخَذۡنَا مِيثَٰقَهُمۡ فَنَسُواْ حَظّٗا مِّمَّا ذُكِّرُواْ بِهِۦ فَأَغۡرَيۡنَا بَيۡنَهُمُ ٱلۡعَدَاوَةَ وَٱلۡبَغۡضَآءَ إِلَىٰ يَوۡمِ ٱلۡقِيَٰمَةِۚ وَسَوۡفَ يُنَبِّئُهُمُ ٱللَّهُ بِمَا كَانُواْ يَصۡنَعُونَ ١٤","ومن الذين قالوا إنا نصارى أخذنا ميثاقهم فنسوا حظا مما ذكروا به فأغرينا بينهم العداوة والبغضاء إلى يوم القيامة وسوف ينبئهم الله بما كانوا يصنعون","ހަމަކަށަވަރުން، ތިމަންމެންނީ ނަސާރާ އިންނޭ ބުނިމީހުންގެ ކިބައިންވެސް އެއުރެންގެ ކަށަވަރުވެގެންވާ އަހުދު ތިމަންރަސްކަލާނގެ ހިއްޕެވީމެވެ. ދެން އެއުރެންނަށް ހަނދާންކޮށްދެއްވި ކަންތަކުގެ ތެރެއިން އެއުރެން ހަނދާންނައްތާލިއެވެ. ފަހެ، ގިޔާމަތް ދުވަހަށް ދާނދެން އެއުރެންގެ މެދުގައި، ޢަދާވާތް ތެރިކަމާއި، ރުޅިވެރިކަން ލެއްވީމެވެ. އަދި ނިކަންހުރެ އެއުރެން ކޮށްއުޅުނު ޢަމަލުތަކުގެ ވާހަކައިން ﷲއެއުރެންނަށް ޚަބަރު އަންގަވާނެއެވެ.","",""],["₅ سورة المائدة","15","يَـٰٓأَهۡلَ ٱلۡكِتَٰبِ قَدۡ جَآءَكُمۡ رَسُولُنَا يُبَيِّنُ لَكُمۡ كَثِيرٗا مِّمَّا كُنتُمۡ تُخۡفُونَ مِنَ ٱلۡكِتَٰبِ وَيَعۡفُواْ عَن كَثِيرٖۚ قَدۡ جَآءَكُم مِّنَ ٱللَّهِ نُورٞ وَكِتَٰبٞ مُّبِينٞ ١٥","يا أهل الكتاب قد جاءكم رسولنا يبين لكم كثيرا مما كنتم تخفون من الكتاب ويعفو عن كثير قد جاءكم من الله نور وكتاب مبين","އޭ ފޮތުގެ އަހުލުވެރިންނޭވެ! ފޮތުން ތިޔަބައިމީހުން ވަންހަނާކޮށް އުޅުނު ކަންތަކުގެ ތެރެއިން ގިނަ ކަންތައްތަކެއް ތިޔަބައިމީހުންނަށް ބަޔާންކޮށްދެއްވާ އަދި (އޭގެ) ގިނަ ކަންތައްތައް އަފޫކުރައްވާ ޙާލު، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ރަސޫލާ ތިޔަބައިމީހުންގެ ގާތަށް ވަޑައިގެންފިއެވެ. ހަމަކަށަވަރުން، ﷲގެ ހަޒުރަތުން ނޫރަކާއި، ބަޔާންކުރަނިވި ފޮތެއް، ތިޔަބައިމީހުންގެ ގާތަށް އަތުވެއްޖެއެވެ.","",""],["₅ سورة المائدة","16","يَهۡدِي بِهِ ٱللَّهُ مَنِ ٱتَّبَعَ رِضۡوَٰنَهُۥ سُبُلَ ٱلسَّلَٰمِ وَيُخۡرِجُهُم مِّنَ ٱلظُّلُمَٰتِ إِلَى ٱلنُّورِ بِإِذۡنِهِۦ وَيَهۡدِيهِمۡ إِلَىٰ صِرَٰطٖ مُّسۡتَقِيمٖ ١٦","يهدي به الله من اتبع رضوانه سبل السلام ويخرجهم من الظلمات إلى النور بإذنه ويهديهم إلى صراط مستقيم","ﷲ، އެކަލާނގެ ރުއްސަވާ މަގަށް ތަބާ ވީ މީހަކަށް ސަލާމަތުގެ މަގަށް އެފޮތުން މަގުދައްކަވަތެވެ. އަދި އެކަލާނގެ އިޒުނަފުޅުން އަނދިރިކަމުގެ ތެރެއިން އަލިކަމުގެ ތެރެޔަށް އެއުރެން ނެރުއްވަތެވެ. އަދި ސީދާވެގެންވާ ތެދުމަގަކަށް އެއުރެންނަށް މަގުދައްކަވަތެވެ.","",""],["₅ سورة المائدة","17","لَّقَدۡ كَفَرَ ٱلَّذِينَ قَالُوٓاْ إِنَّ ٱللَّهَ هُوَ ٱلۡمَسِيحُ ٱبۡنُ مَرۡيَمَۚ قُلۡ فَمَن يَمۡلِكُ مِنَ ٱللَّهِ شَيۡـًٔا إِنۡ أَرَادَ أَن يُهۡلِكَ ٱلۡمَسِيحَ ٱبۡنَ مَرۡيَمَ وَأُمَّهُۥ وَمَن فِي ٱلۡأَرۡضِ جَمِيعٗاۗ وَلِلَّهِ مُلۡكُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ وَمَا بَيۡنَهُمَاۚ يَخۡلُقُ مَا يَشَآءُۚ وَٱللَّهُ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٞ ١٧","لقد كفر الذين قالوا إن الله هو المسيح ابن مريم قل فمن يملك من الله شيئا إن أراد أن يهلك المسيح ابن مريم وأمه ومن في الأرض جميعا ولله ملك السماوات والأرض وما بينهما يخلق ما يشاء والله على كل شيء قدير","ހަމަކަށަވަރުން، ﷲއީ، މަރިޔަމްގެފާނުންގެ ދަރިކަލުން އަލްމަސީޙު (ޢީސާގެފާނު) ކަމަށް ބުނި މީހުން ކާފިރު ވެއްޖެކަން ކަށަވަރެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ފަހެ، މަރިޔަމްގެފާނުގެ ދަރިކަލުން އަލްމަސީޙު (ޢީސާގެފާނު) އާއި، އެކަލޭގެފާނުގެ މައިކަނބަލުންނާއި، ބިމުގައިވާހައި ބަޔަކު ނެތިކުރެއްވުމަށް ﷲ އިރާދަކުރައްވައިފިނަމަ، ﷲގެ އިރާދަފުޅާ ދެކޮޅަށް ކަމެއް ކުރުމަށް އެއްވެސް ބާރެއް ލިބިގެންވަނީ ކާކަށްހެއްޔެވެ؟ އުޑުތަކާއި، ބިމާއި، އެދެމެދުގައި ވާހާ ތަކެއްޗެއްގެ ވެރިކަންވަނީ ﷲއަށެވެ. އެކަލާނގެ އިރާދަކުރެއްވި އެއްޗެއް ހައްދަވަތެވެ. އަދި ﷲއީ، ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","18","وَقَالَتِ ٱلۡيَهُودُ وَٱلنَّصَٰرَىٰ نَحۡنُ أَبۡنَـٰٓؤُاْ ٱللَّهِ وَأَحِبَّـٰٓؤُهُۥۚ قُلۡ فَلِمَ يُعَذِّبُكُم بِذُنُوبِكُمۖ بَلۡ أَنتُم بَشَرٞ مِّمَّنۡ خَلَقَۚ يَغۡفِرُ لِمَن يَشَآءُ وَيُعَذِّبُ مَن يَشَآءُۚ وَلِلَّهِ مُلۡكُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ وَمَا بَيۡنَهُمَاۖ وَإِلَيۡهِ ٱلۡمَصِيرُ ١٨","وقالت اليهود والنصارى نحن أبناء الله وأحباؤه قل فلم يعذبكم بذنوبكم بل أنتم بشر ممن خلق يغفر لمن يشاء ويعذب من يشاء ولله ملك السماوات والأرض وما بينهما وإليه المصير","ޔަހޫދީންނާއި، ނަސާރާ އިން ބުނެފޫއެވެ. ތިމަންމެންނީ، ﷲގެ ދަރިންނެވެ. އަދި އެކަލާނގެ ލޯބިވެވޮޑިގެންވާ މީހުންނެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެހެންވިއްޔާ ތިޔަބައިމީހުންގެ ފާފަތަކުގެ ސަބަބުން ތިޔަބައިމީހުންނަށް އެކަލާނގެ އަޒާބު ދެއްވަނީ ކީއްވެގެންހެއްޔެވެ؟ އަދި ކިއެއްތަ! ތިޔަބައިމީހުންނީ، އެކަލާނގެ ހެއްދެވި މީހުންގެ ތެރެއިންވާ މީހުންނެވެ. އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ފާފަފުއްސަވަތެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް އަޒާބު ދެއްވަތެވެ. އަދި އުޑުތަކާއި، ބިމާއި، އެ ދެމެދުގައި ވާހާ ތަކެއްޗެއްގެ ވެރިކަން މަލަކަ ވެގެންވަނީ ﷲއަށެވެ. އަދި ނިމިދިއުންވަނީވެސް އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["₅ سورة المائدة","19","يَـٰٓأَهۡلَ ٱلۡكِتَٰبِ قَدۡ جَآءَكُمۡ رَسُولُنَا يُبَيِّنُ لَكُمۡ عَلَىٰ فَتۡرَةٖ مِّنَ ٱلرُّسُلِ أَن تَقُولُواْ مَا جَآءَنَا مِنۢ بَشِيرٖ وَلَا نَذِيرٖۖ فَقَدۡ جَآءَكُم بَشِيرٞ وَنَذِيرٞۗ وَٱللَّهُ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٞ ١٩","يا أهل الكتاب قد جاءكم رسولنا يبين لكم على فترة من الرسل أن تقولوا ما جاءنا من بشير ولا نذير فقد جاءكم بشير ونذير والله على كل شيء قدير","އޭ ފޮތުގެ އަހުލުވެރިންނޭވެ! އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކުވިޔަސް، އަދި ބިރުވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކުވިޔަސް، ތިމަންމެންގެ ގާތަކަށް ވަޑައެއްނުގަންނަވައޭ ތިޔަބައިމީހުން ބުނެފާނެކަމަށްޓަކައި، ރަސޫލުންގެ މެދުކެނޑުމަކަށްފަހު، ތިޔަބައިމީހުންނަށް (ކަންތައްތައް) ބަޔާން ކޮށްދެއްވާ ޙާލު ތިޔަބައިމީހުންގެ ގާތަށް ތިމަންރަސްކަލާނގެ ރަސޫލާ ވަޑައިގެންފިކަން ކަށަވަރެވެ. ފަހެ، އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާ، އަދި ބިރުވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު ތިޔަބައިމީހުންގެ ގާތަށް ވަޑައިގެންފިކަން ކަށަވަރެވެ. ﷲއީ، ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","20","وَإِذۡ قَالَ مُوسَىٰ لِقَوۡمِهِۦ يَٰقَوۡمِ ٱذۡكُرُواْ نِعۡمَةَ ٱللَّهِ عَلَيۡكُمۡ إِذۡ جَعَلَ فِيكُمۡ أَنۢبِيَآءَ وَجَعَلَكُم مُّلُوكٗا وَءَاتَىٰكُم مَّا لَمۡ يُؤۡتِ أَحَدٗا مِّنَ ٱلۡعَٰلَمِينَ ٢٠","وإذ قال موسى لقومه يا قوم اذكروا نعمة الله عليكم إذ جعل فيكم أنبياء وجعلكم ملوكا وآتاكم ما لم يؤت أحدا من العالمين","އަދި މޫސާގެފާނު، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް ވިދާޅުވިހިނދު ހަނދުމަކުރާށެވެ! އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުންގެ މައްޗަށް ﷲ ދެއްވި ނިއުމަތް ތިޔަބައިމީހުން ހަނދުމަކުރާށެވެ! އެހެނީ، އެކަލާނގެ ތިޔަބައިމީހުންގެ ތެރޭގައި ނަބީބޭކަލުން ލެއްވިއެވެ. އަދި ތިޔަބައިމީހުން (ގެތެރެއިން ބަޔަކު) ރަސްކަލުންތަކެއް ކަމުގައި ލެއްވިއެވެ. އަދި (އެޒަމާނުގެ) އާލަމްތަކުގެ ތެރެއިން އެކަކަށްވެސް ނުދެއްވާ ނިއުމަތް ތިޔަބައިމީހުންނަށް ދެއްވިއެވެ.","",""],["₅ سورة المائدة","21","يَٰقَوۡمِ ٱدۡخُلُواْ ٱلۡأَرۡضَ ٱلۡمُقَدَّسَةَ ٱلَّتِي كَتَبَ ٱللَّهُ لَكُمۡ وَلَا تَرۡتَدُّواْ عَلَىٰٓ أَدۡبَارِكُمۡ فَتَنقَلِبُواْ خَٰسِرِينَ ٢١","يا قوم ادخلوا الأرض المقدسة التي كتب الله لكم ولا ترتدوا على أدباركم فتنقلبوا خاسرين","އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! މުގައްދަސް ވެގެންވާ ބިމަށް، ތިޔަބައިމީހުން ވަންނާށެވެ! އެ ބިމަކީ ތިޔަބައިމީހުންނަށްޓަކައި ﷲ ކަނޑައަޅުއްވާފައިވާ ބިމެވެ. އަދި ތިޔަބައިމީހުން ފުރަގަސްދީ، އެނބުރި ނުގަންނާށެވެ! އޭރުން ތިޔަބައިމީހުން ގެއްލެނިވެގެންވާ ބަޔަކުކަމުގައި ވެގެން ހިނގައިދާނެތެވެ.","",""],["₅ سورة المائدة","22","قَالُواْ يَٰمُوسَىٰٓ إِنَّ فِيهَا قَوۡمٗا جَبَّارِينَ وَإِنَّا لَن نَّدۡخُلَهَا حَتَّىٰ يَخۡرُجُواْ مِنۡهَا فَإِن يَخۡرُجُواْ مِنۡهَا فَإِنَّا دَٰخِلُونَ ٢٢","قالوا يا موسى إن فيها قوما جبارين وإنا لن ندخلها حتى يخرجوا منها فإن يخرجوا منها فإنا داخلون","އެއުރެން ދެންނެވޫއެވެ. އޭ މޫސާގެފާނެވެ! ހަމަކަށަވަރުން، ގަދަފަދަ ޖައްބާރު ބަޔަކު އެތާނގައި އެބަތިއްބެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެން އެތަނުން ނުކުމެއްޖައުމަށްދާނދެން، ތިމަންމެން އެތަނަކަށް ނުވަންނާނޫއެވެ. ފަހެ، އެއުރެން އެތަނުން ނުކުންނަނީނަމަ، ހަމަކަށަވަރުން، ތިމަންމެންނީ އެތަނަށް ވަންނާނޭ ބަޔަކީމުއެވެ.","",""],["₅ سورة المائدة","23","قَالَ رَجُلَانِ مِنَ ٱلَّذِينَ يَخَافُونَ أَنۡعَمَ ٱللَّهُ عَلَيۡهِمَا ٱدۡخُلُواْ عَلَيۡهِمُ ٱلۡبَابَ فَإِذَا دَخَلۡتُمُوهُ فَإِنَّكُمۡ غَٰلِبُونَۚ وَعَلَى ٱللَّهِ فَتَوَكَّلُوٓاْ إِن كُنتُم مُّؤۡمِنِينَ ٢٣","قال رجلان من الذين يخافون أنعم الله عليهما ادخلوا عليهم الباب فإذا دخلتموه فإنكم غالبون وعلى الله فتوكلوا إن كنتم مؤمنين","(ﷲ ދެކެ) ބިރުވެތިވާ މީހުންގެ ތެރެއިން ﷲ، ނިއުމަތް ދެއްވާފައިވާ ދެމީހަކު ބުންޏެވެ. އެއުރެންނާ ދިމާޔަށް (އެރަށުގެ) ދޮރޯށިން ތިޔަބައިމީހުން ވަދެގެން ދާށެވެ! ފަހެ، ތިޔަބައިމީހުން އެރަށަށް ވަދެއްޖެނަމަ، ތިޔަބައިމީހުންނީ، (އެއުރެންގެ މައްޗަށް) ގަދަވެގަންނާނޭ ބަޔަކުކަން ކަށަވަރެވެ. އަދި ތިޔަބައިމީހުންނީ، އީމާން ވެގެންތިބި ބަޔަކުކަމުގައިވާނަމަ، ހަމައެކަނި ﷲއަށް ތިޔަބައިމީހުން ވަކީލުކުރާށެވެ!","",""],["₅ سورة المائدة","24","قَالُواْ يَٰمُوسَىٰٓ إِنَّا لَن نَّدۡخُلَهَآ أَبَدٗا مَّا دَامُواْ فِيهَا فَٱذۡهَبۡ أَنتَ وَرَبُّكَ فَقَٰتِلَآ إِنَّا هَٰهُنَا قَٰعِدُونَ ٢٤","قالوا يا موسى إنا لن ندخلها أبدا ما داموا فيها فاذهب أنت وربك فقاتلا إنا هاهنا قاعدون","އެއުރެން ދެންނެވޫއެވެ. އޭ މޫސާގެފާނެވެ! އެއުރެން އެރަށުގައި ދެމިތިބިހައިހިނދަކު އެއްގޮތަކަށްވެސް ތިމަންމެން އެރަށަކަށް ނުވަންނާނޫއެވެ. ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއާއި، ކަލޭގެފާނު ވަޑައިގެން އެއުރެންނާ ހަނގުރާމަ ކުރައްވާށެވެ! ތިމަންމެން މިތާނގައި ތިބޭނޫއެވެ.","",""],["₅ سورة المائدة","25","قَالَ رَبِّ إِنِّي لَآ أَمۡلِكُ إِلَّا نَفۡسِي وَأَخِيۖ فَٱفۡرُقۡ بَيۡنَنَا وَبَيۡنَ ٱلۡقَوۡمِ ٱلۡفَٰسِقِينَ ٢٥","قال رب إني لا أملك إلا نفسي وأخي فافرق بيننا وبين القوم الفاسقين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. މިއަޅާގެ ވެރިރަސްކަލާކޯއެވެ! މިއަޅާގެ އަޚާއި، މިއަޅާގެ އަމިއްލަ ނަފްސު މެނުވީ މިއަޅާޔަށް މިލްކުވެގެނެއް ނުވެއެވެ. ފަހެ، ފާސިގު ވީ މީހުންނާއި އަޅަމެންނާ ދެމެދު ނިޔާއެއް ކުރައްވައިފާނދޭވެ!","",""],["₅ سورة المائدة","26","قَالَ فَإِنَّهَا مُحَرَّمَةٌ عَلَيۡهِمۡۛ أَرۡبَعِينَ سَنَةٗۛ يَتِيهُونَ فِي ٱلۡأَرۡضِۚ فَلَا تَأۡسَ عَلَى ٱلۡقَوۡمِ ٱلۡفَٰسِقِينَ ٢٦","قال فإنها محرمة عليهم أربعين سنة يتيهون في الأرض فلا تأس على القوم الفاسقين","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ހަމަކަށަވަރުން، އެކަން (އެބަހީ: މުގައްދަސް ވެގެންވާ ރަށުގެ ބިމަށް ވަނުން) އެއުރެންގެ މައްޗަށް ހަރާމްކުރައްވާފައިވެއެވެ. ސާޅީސް އަހަރުވާންދެނެވެ. ދެވޭނުދެވޭ ތަނެއް ނޭނގި ބިމުގައި ބެހިގެން އެއުރެން އުޅުމަށެވެ. ފަހެ، ފާސިގުވި ގައުމުގެމީހުންގެ މައްޗަށް ކަލޭގެފާނު ހިތާމަ ނުކުރައްވާށެވެ!","",""],["₅ سورة المائدة","27","۞وَٱتۡلُ عَلَيۡهِمۡ نَبَأَ ٱبۡنَيۡ ءَادَمَ بِٱلۡحَقِّ إِذۡ قَرَّبَا قُرۡبَانٗا فَتُقُبِّلَ مِنۡ أَحَدِهِمَا وَلَمۡ يُتَقَبَّلۡ مِنَ ٱلۡأٓخَرِ قَالَ لَأَقۡتُلَنَّكَۖ قَالَ إِنَّمَا يَتَقَبَّلُ ٱللَّهُ مِنَ ٱلۡمُتَّقِينَ ٢٧","واتل عليهم نبأ ابني آدم بالحق إذ قربا قربانا فتقبل من أحدهما ولم يتقبل من الآخر قال لأقتلنك قال إنما يتقبل الله من المتقين","އާދަމުގެފާނުގެ ދެދަރިކަލުންގެ ޚަބަރު، ހައްގު ގޮތުގައި ކަލޭގެފާނު އެއުރެންނަށް ކިޔައިދެއްވާށެވެ! އެއީ، އެ ދެދަރިކަލުން ގުރުބާނެއް ކުރިމަތިކުރެއްވިހިނދު (ކަންހިނގިގޮތުގެ ވާހަކަ) އެވެ. ފަހެ، އެ ދެދަރިކަލުންކުރެ އެއްދަރިކަލެއްގެ ކިބައިން (ގުރުބާން) ގަބޫލުކުރެއްވިއެވެ. އަނެއް ދަރިކަލުންގެ ކިބައިން ގަބޫލެއް ނުކުރެއްވިއެވެ. އެ ދަރިކަލުން ވިދާޅުވިއެވެ. ތިމަން، ކަށަވަރުންވެސް ކަލޭ ގަތުލުކުރާހުށީމެވެ. އަނެއް ދަރިކަލުން ވިދާޅުވިއެވެ. ﷲ ގަބޫލުކުރައްވާކަން ކަށަވަރީ ތަގުވާވެރިންގެ ކިބައިންނެވެ.","",""],["₅ سورة المائدة","28","لَئِنۢ بَسَطتَ إِلَيَّ يَدَكَ لِتَقۡتُلَنِي مَآ أَنَا۠ بِبَاسِطٖ يَدِيَ إِلَيۡكَ لِأَقۡتُلَكَۖ إِنِّيٓ أَخَافُ ٱللَّهَ رَبَّ ٱلۡعَٰلَمِينَ ٢٨","لئن بسطت إلي يدك لتقتلني ما أنا بباسط يدي إليك لأقتلك إني أخاف الله رب العالمين","ހަމަކަށަވަރުން، ތިމަން ގަތުލުކުރުމަށްޓަކައި ކަލޭގެ އަތް ތިމަންނަޔާ ދިމާޔަށް ދިއްކުރިއަސް، ކަލޭ ގަތުލުކުރުމަށްޓަކައި، ތިމަންގެ އަތް ކަލެޔާ ދިމާޔަށް ދިއްކުރާނޭ މީހަކު ކަމުގައި ތިމަން ނުވަމެވެ. ހަމަކަށަވަރުން، އާލަމް ތަކުގެވެރި ﷲ ދެކެ ތިމަން ބިރުގަންނަމެވެ.","",""],["₅ سورة المائدة","29","إِنِّيٓ أُرِيدُ أَن تَبُوٓأَ بِإِثۡمِي وَإِثۡمِكَ فَتَكُونَ مِنۡ أَصۡحَٰبِ ٱلنَّارِۚ وَذَٰلِكَ جَزَـٰٓؤُاْ ٱلظَّـٰلِمِينَ ٢٩","إني أريد أن تبوء بإثمي وإثمك فتكون من أصحاب النار وذلك جزاء الظالمين","ހަމަކަށަވަރުން، ތިމަން އެދެނީ ތިމަންގެ ފާފައާއި ކަލޭގެ ފާފައާއިގެން (ﷲގެ ހަޒުރަތަށް) ކަލޭ ރުޖޫއަ ވުމެވެ. އޭރުން ކަލޭވާހުށީ، ނަރަކައިގެ އަހުލުވެރިންގެ ތެރެއިންނެވެ. އެއީ އަނިޔާވެރިންގެ ޖަޒާއެވެ.","",""],["₅ سورة المائدة","30","فَطَوَّعَتۡ لَهُۥ نَفۡسُهُۥ قَتۡلَ أَخِيهِ فَقَتَلَهُۥ فَأَصۡبَحَ مِنَ ٱلۡخَٰسِرِينَ ٣٠","فطوعت له نفسه قتل أخيه فقتله فأصبح من الخاسرين","ދެން އޭނާގެ އަޚާ ގަތުލުކުރުމަށް، އޭނާގެ ނަފްސު އޭނާޔަށް ޒީނަތް ތެރިކޮށް ދައްކައި ފަހިކޮށްދިނެވެ. ދެން އޭނާ، އޭނާގެ އަޚާ ގަތުލުކުޅައެވެ. ދެން އޭނާ، ގެއްލެނިވެގެންވާ މީހުންގެ ތެރެއިންވިއެވެ.","",""],["₅ سورة المائدة","31","فَبَعَثَ ٱللَّهُ غُرَابٗا يَبۡحَثُ فِي ٱلۡأَرۡضِ لِيُرِيَهُۥ كَيۡفَ يُوَٰرِي سَوۡءَةَ أَخِيهِۚ قَالَ يَٰوَيۡلَتَىٰٓ أَعَجَزۡتُ أَنۡ أَكُونَ مِثۡلَ هَٰذَا ٱلۡغُرَابِ فَأُوَٰرِيَ سَوۡءَةَ أَخِيۖ فَأَصۡبَحَ مِنَ ٱلنَّـٰدِمِينَ ٣١","فبعث الله غرابا يبحث في الأرض ليريه كيف يواري سوءة أخيه قال يا ويلتى أعجزت أن أكون مثل هذا الغراب فأواري سوءة أخي فأصبح من النادمين","ދެން އޭނާގެ އަޚާގެ (ފުރާނަނެތް) މަސްގަނޑު ނިވާކުރާނީ ކޮންފަދަޔަކުންކަން އޭނާއަށް ދެއްކެވުމަށްޓަކައި، ބިން ހާވާނޭ ކާޅެއް ﷲ ފޮނުއްވިއެވެ. ދެން، އޭނާ ބުންޏެވެ. އޭ، އަހުރެންނަށް ހުރި ހިތާމަޔެއްގެ ބޮޑުކަމާއެވެ! އަހުރެންގެ އަޚާގެ މަސްގަނޑު ނިވާކުޅައުމަށް، މި ކާޅު ފަދައިންވުމަށްވެސް، އަހުރެން ނުކުޅެދިގެން ވީހެއްޔެވެ؟ ދެން، އޭނާ ހިތާމަކުރާ މީހުންގެ ތެރެއިންވިއެވެ.","",""],["₅ سورة المائدة","32","مِنۡ أَجۡلِ ذَٰلِكَ كَتَبۡنَا عَلَىٰ بَنِيٓ إِسۡرَـٰٓءِيلَ أَنَّهُۥ مَن قَتَلَ نَفۡسَۢا بِغَيۡرِ نَفۡسٍ أَوۡ فَسَادٖ فِي ٱلۡأَرۡضِ فَكَأَنَّمَا قَتَلَ ٱلنَّاسَ جَمِيعٗا وَمَنۡ أَحۡيَاهَا فَكَأَنَّمَآ أَحۡيَا ٱلنَّاسَ جَمِيعٗاۚ وَلَقَدۡ جَآءَتۡهُمۡ رُسُلُنَا بِٱلۡبَيِّنَٰتِ ثُمَّ إِنَّ كَثِيرٗا مِّنۡهُم بَعۡدَ ذَٰلِكَ فِي ٱلۡأَرۡضِ لَمُسۡرِفُونَ ٣٢","من أجل ذلك كتبنا على بني إسرائيل أنه من قتل نفسا بغير نفس أو فساد في الأرض فكأنما قتل الناس جميعا ومن أحياها فكأنما أحيا الناس جميعا ولقد جاءتهم رسلنا بالبينات ثم إن كثيرا منهم بعد ذلك في الأرض لمسرفون","އެކަމަށްޓަކައި އިސްރާއީލުގެދަރިންގެ މައްޗަށް، ތިމަންރަސްކަލާނގެ ކަނޑައެޅުއްވީމެވެ. ނަފްސެއް މަރައިގެން، ނުވަތަ ބިމުގައި ފަސާދެއް އުފައްދައިގެން ނޫންގޮތަކަށް، ނަފްސެއް މަރައިފި މީހަކު، އެންމެހާ މީސްތަކުން މެރިފަދައެވެ. އަދި އެ ނަފްސު ދިރުވައިފި މީހާ (އެބަހީ: ނުމަރައި ދުނިޔޭގައި ބަހައްޓައިފިމީހާ) އެންމެހާ މީސްތަކުން ދިރުވިފަދައެވެ. ހަމަކަށަވަރުން، ބަޔާން ވެގެންވާ ހެކިތަކާއިގެން، ތިމަންރަސްކަލާނގެ ރަސޫލުން އެއުރެންގެ ގާތަށް ވަޑައިގަތެވެ. ދެން އެއަށްފަހު، އެއުރެންގެ ތެރެއިން ގިނަމީހުންނީ ބިމުގައި އިސްރާފު ކޮށްއުޅޭ މީހުންކަން ކަށަވަރެވެ. (އެބަހީ: މީހުން މެރުމާއި، ކާފިރުކަމުގައި ހައްދުފަހަނަޅައި ގޮސްފައިވާ މީހުންކަން ކަށަވަރެވެ.)","",""],["₅ سورة المائدة","33","إِنَّمَا جَزَـٰٓ‌ؤُاْ ٱلَّذِينَ يُحَارِبُونَ ٱللَّهَ وَرَسُولَهُۥ وَيَسۡعَوۡنَ فِي ٱلۡأَرۡضِ فَسَادًا أَن يُقَتَّلُوٓاْ أَوۡ يُصَلَّبُوٓاْ أَوۡ تُقَطَّعَ أَيۡدِيهِمۡ وَأَرۡجُلُهُم مِّنۡ خِلَٰفٍ أَوۡ يُنفَوۡاْ مِنَ ٱلۡأَرۡضِۚ ذَٰلِكَ لَهُمۡ خِزۡيٞ فِي ٱلدُّنۡيَاۖ وَلَهُمۡ فِي ٱلۡأٓخِرَةِ عَذَابٌ عَظِيمٌ ٣٣","إنما جزاء الذين يحاربون الله ورسوله ويسعون في الأرض فسادا أن يقتلوا أو يصلبوا أو تقطع أيديهم وأرجلهم من خلاف أو ينفوا من الأرض ذلك لهم خزي في الدنيا ولهم في الآخرة عذاب عظيم","ﷲއާއި، އެކަލާނގެ ރަސޫލާއާ ހަނގުރާމަކޮށް އުޅޭ މީހުންނާއި، ބިމުގައި ފަސާދަކުރުމަށް މަސައްކަތް ކޮށްއުޅޭ މީހުންގެ ޖަޒާއެއް ކަމުގައިވާކަން ކަށަވަރީ އެއުރެން މެރުމެވެ. ނުވަތަ ޞަލީބަށް އެރުވުމެވެ. ނުވަތަ، ތަފާތުކޮށް އެއުރެންގެ އަތްފައި ބުރިކުރުމެވެ. (އެބަހީ: ކަނާތާއި، ވާތުފައި ނުވަތަ ވާތާއި، ކަނާތުފައި ބުރިކުރުމެވެ.) ނުވަތަ، ރަށުން ފޮނުވައިލުމެވެ. އެއީ އެއުރެންނަށް ދުނިޔޭގައި ހުރި ނިކަމެތިކަމެވެ. އަދި އާޚިރަތުގައި، އެއުރެންނަށް ބޮޑުވެގެންވާ އަޒާބު ހުށްޓެވެ.","",""],["₅ سورة المائدة","34","إِلَّا ٱلَّذِينَ تَابُواْ مِن قَبۡلِ أَن تَقۡدِرُواْ عَلَيۡهِمۡۖ فَٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ غَفُورٞ رَّحِيمٞ ٣٤","إلا الذين تابوا من قبل أن تقدروا عليهم فاعلموا أن الله غفور رحيم","އެއުރެންގެ މައްޗަށް ތިޔަބައިމީހުން ގަދަވެގަތުމުގެ ކުރިން، ތައުބާވި މީހުން މެނުވީއެވެ. ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެކަން، ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₅ سورة المائدة","35","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ ٱتَّقُواْ ٱللَّهَ وَٱبۡتَغُوٓاْ إِلَيۡهِ ٱلۡوَسِيلَةَ وَجَٰهِدُواْ فِي سَبِيلِهِۦ لَعَلَّكُمۡ تُفۡلِحُونَ ٣٥","يا أيها الذين آمنوا اتقوا الله وابتغوا إليه الوسيلة وجاهدوا في سبيله لعلكم تفلحون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި އެކަލާނގެ ހަޒުރަތަށް ކުއްތަންވުމުގެ މަގު ތިޔަބައިމީހުން އެދޭށެވެ! އަދި އެކަލާނގެ މަގުގައި ތިޔަބައިމީހުން ޖިހާދުކުރާށެވެ! (އެއީ) ތިޔަބައިމީހުން، ދިންނަވައި ނަސީބު ލިބުމަށްޓަކައެވެ.","",""],["₅ سورة المائدة","36","إِنَّ ٱلَّذِينَ كَفَرُواْ لَوۡ أَنَّ لَهُم مَّا فِي ٱلۡأَرۡضِ جَمِيعٗا وَمِثۡلَهُۥ مَعَهُۥ لِيَفۡتَدُواْ بِهِۦ مِنۡ عَذَابِ يَوۡمِ ٱلۡقِيَٰمَةِ مَا تُقُبِّلَ مِنۡهُمۡۖ وَلَهُمۡ عَذَابٌ أَلِيمٞ ٣٦","إن الذين كفروا لو أن لهم ما في الأرض جميعا ومثله معه ليفتدوا به من عذاب يوم القيامة ما تقبل منهم ولهم عذاب أليم","ހަމަކަށަވަރުން، ކާފިރުވި މީހުން، ގިޔާމަތް ދުވަހުގެ އަޒާބުން އެއުރެން ސަލާމަތްވެގަތުމަށް އެތަކެތިން ފިދުޔަ ދިނުމަށްޓަކައި، ބިމުގައިވާ އެންމެހާ ތަކެއްޗާއި، އެއާއެކު ހަމައެފަދަ ތަކެތި، އެއުރެންނަށް މިލްކުވެގެންވީ ނަމަވެސް، އެއުރެންގެ ކިބައިން ގަބޫލެއް ނުކުރެއްވީހެވެ. އަދި އެއުރެންނަށް ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["₅ سورة المائدة","37","يُرِيدُونَ أَن يَخۡرُجُواْ مِنَ ٱلنَّارِ وَمَا هُم بِخَٰرِجِينَ مِنۡهَاۖ وَلَهُمۡ عَذَابٞ مُّقِيمٞ ٣٧","يريدون أن يخرجوا من النار وما هم بخارجين منها ولهم عذاب مقيم","ނަރަކައިގެ އަލިފާނުގެ ތެރެއިން ނުކުތުމަށް އެއުރެން އެދޭނެތެވެ. (ނަމަވެސް) އެތަނުން ނުކުމެވޭނޭ ބަޔަކު ކަމުގައި، އެއުރެން ނުވެތެވެ. އަދި އެއުރެންނަށް ދެމިހުންނަނިވި އަޒާބު ހުށްޓެވެ.","",""],["₅ سورة المائدة","38","وَٱلسَّارِقُ وَٱلسَّارِقَةُ فَٱقۡطَعُوٓاْ أَيۡدِيَهُمَا جَزَآءَۢ بِمَا كَسَبَا نَكَٰلٗا مِّنَ ٱللَّهِۗ وَٱللَّهُ عَزِيزٌ حَكِيمٞ ٣٨","والسارق والسارقة فاقطعوا أيديهما جزاء بما كسبا نكالا من الله والله عزيز حكيم","ވައްކަންކުރާ ފިރިހެނާއާއި، ވައްކަންކުރާ އަންހެނާ (ދަންނާށެވެ!) ފަހެ، ތިޔަބައިމީހުން އެ ދެމީހުންގެ އަތްތައް ބުރިކުރާށެވެ! (އެއީ) އެ ދެ މީހުން ކުޅަކަންތަކުގެ ޖަޒާއަކަށް، ﷲގެ ހަޒުރަތުން ކަނޑައަޅުއްވާފައިވާ އިބްރަތް ތެރި އުގޫބާތެއްގެ ގޮތުންނެވެ. ﷲއީ، ޢަޒީޒުވަންތަ ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","39","فَمَن تَابَ مِنۢ بَعۡدِ ظُلۡمِهِۦ وَأَصۡلَحَ فَإِنَّ ٱللَّهَ يَتُوبُ عَلَيۡهِۚ إِنَّ ٱللَّهَ غَفُورٞ رَّحِيمٌ ٣٩","فمن تاب من بعد ظلمه وأصلح فإن الله يتوب عليه إن الله غفور رحيم","ފަހެ، އަނިޔާވެރިވުމަށްފަހު، (އެބަހީ: ވައްކަންކުރުމަށްފަހު) ތައުބާވެ (އޭނާގެ ޢަމަލު) އިސްލާހު ކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲ އެމީހާގެ މައްޗަށް ތައުބާ ލައްވާނެތެވެ. ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","40","أَلَمۡ تَعۡلَمۡ أَنَّ ٱللَّهَ لَهُۥ مُلۡكُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ يُعَذِّبُ مَن يَشَآءُ وَيَغۡفِرُ لِمَن يَشَآءُۗ وَٱللَّهُ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٞ ٤٠","ألم تعلم أن الله له ملك السماوات والأرض يعذب من يشاء ويغفر لمن يشاء والله على كل شيء قدير","ހަމަކަށަވަރުން، އުޑުތަކާއި، ބިމުގެ ވެރިކަން ﷲއަށް މިލްކުވެގެންވާކަން ތިބާ ނުދަންނަމުހެއްޔެވެ؟ އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް އެކަލާނގެ އަޒާބު ދެއްވަތެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް އެކަލާނގެ ފާފަފުއްސަވަތެވެ. ﷲއީ، ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","41","۞يَـٰٓأَيُّهَا ٱلرَّسُولُ لَا يَحۡزُنكَ ٱلَّذِينَ يُسَٰرِعُونَ فِي ٱلۡكُفۡرِ مِنَ ٱلَّذِينَ قَالُوٓاْ ءَامَنَّا بِأَفۡوَٰهِهِمۡ وَلَمۡ تُؤۡمِن قُلُوبُهُمۡۛ وَمِنَ ٱلَّذِينَ هَادُواْۛ سَمَّـٰعُونَ لِلۡكَذِبِ سَمَّـٰعُونَ لِقَوۡمٍ ءَاخَرِينَ لَمۡ يَأۡتُوكَۖ يُحَرِّفُونَ ٱلۡكَلِمَ مِنۢ بَعۡدِ مَوَاضِعِهِۦۖ يَقُولُونَ إِنۡ أُوتِيتُمۡ هَٰذَا فَخُذُوهُ وَإِن لَّمۡ تُؤۡتَوۡهُ فَٱحۡذَرُواْۚ وَمَن يُرِدِ ٱللَّهُ فِتۡنَتَهُۥ فَلَن تَمۡلِكَ لَهُۥ مِنَ ٱللَّهِ شَيۡـًٔاۚ أُوْلَـٰٓئِكَ ٱلَّذِينَ لَمۡ يُرِدِ ٱللَّهُ أَن يُطَهِّرَ قُلُوبَهُمۡۚ لَهُمۡ فِي ٱلدُّنۡيَا خِزۡيٞۖ وَلَهُمۡ فِي ٱلۡأٓخِرَةِ عَذَابٌ عَظِيمٞ ٤١","يا أيها الرسول لا يحزنك الذين يسارعون في الكفر من الذين قالوا آمنا بأفواههم ولم تؤمن قلوبهم ومن الذين هادوا سماعون للكذب سماعون لقوم آخرين لم يأتوك يحرفون الكلم من بعد مواضعه يقولون إن أوتيتم هذا فخذوه وإن لم تؤتوه فاحذروا ومن يرد الله فتنته فلن تملك له من الله شيئا أولئك الذين لم يرد الله أن يطهر قلوبهم لهم في الدنيا خزي ولهم في الآخرة عذاب عظيم","އޭ ރަސޫލާއެވެ! އެއުރެންގެ ހިތްތައް އީމާން ނުވެ، އެއުރެންގެ އަނގައިން ތިމަންމެން އީމާން ވެއްޖައީމުއޭ ބުނި މީހުންގެ ތެރެއިންނާއި، ޔަހޫދީން ކަމުގައިވި މީހުންގެ ތެރެއިން ކާފިރު ވުމަށް އަވަސްވެގަންނަ މީހުންނާމެދު، ކަލޭގެފާނު ހިތާމަ ނުކުރައްވާށެވެ! އެއުރެންނަކީ، ދޮގުތައް ގިނަގިނައިން އަޑުއަހާ މީހުންނެވެ. (އަދި) ކަލޭގެފާނުގެ އަރިހަށް ނާންނަ އެހެންބަޔެއްގެ ބަސް، ގިނަގިނައިން އަޑުއަހާ މީހުންނެވެ. (ތައުރާތުގެ) ކަލިމަތައް އެ ހުންނަންވީ ތަންތަނުން އެއުރެން ބަދަލުކުރެތެވެ. އެއުރެން ބުނެތެވެ. ތިޔަބައިމީހުންނަށް މި ކަލިމަތައް (އެބަހީ: ބަދަލުކުރި ކަލިމަތައް) ލިބިއްޖެނަމަ، އޭގައި ތިޔަބައިމީހުން ހިފަހައްޓާށެވެ! އެ ކަލިމަތައް ތިޔަބައިމީހުންނަށް ނުލިބުނުނަމަ، ތިޔަބައިމީހުން ރައްކާތެރިވާށެވެ! ﷲ އެ މީހަކު މަގުފުރެއްދެވުމަށް އިރާދަކުރައްވާ މީހާ (ދަންނާށެވެ!) ފަހެ، ﷲގެ ހަޒުރަތުން އެމީހަކަށްޓަކައި އެއްވެސް ކަމެއް ކަލޭގެފާނަކަށް މިލްކުވެގެނެއް ނުވާނެއެވެ. އެއުރެންނަކީ، އެއުރެންގެ ހިތްތައް ތާހިރުކުރެއްވުމަށް ﷲ އިރާދަކުރައްވާފައިނުވާ މީހުންނެވެ. އެއުރެންނަށް ދުނިޔޭގައި ހުރީ ނިކަމެތިކަމެވެ. އަދި އާޚިރަތުގައި އެއުރެންނަށް ބޮޑުވެގެންވާ އަޒާބު ހުށްޓެވެ.","",""],["₅ سورة المائدة","42","سَمَّـٰعُونَ لِلۡكَذِبِ أَكَّـٰلُونَ لِلسُّحۡتِۚ فَإِن جَآءُوكَ فَٱحۡكُم بَيۡنَهُمۡ أَوۡ أَعۡرِضۡ عَنۡهُمۡۖ وَإِن تُعۡرِضۡ عَنۡهُمۡ فَلَن يَضُرُّوكَ شَيۡـٔٗاۖ وَإِنۡ حَكَمۡتَ فَٱحۡكُم بَيۡنَهُم بِٱلۡقِسۡطِۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلۡمُقۡسِطِينَ ٤٢","سماعون للكذب أكالون للسحت فإن جاءوك فاحكم بينهم أو أعرض عنهم وإن تعرض عنهم فلن يضروك شيئا وإن حكمت فاحكم بينهم بالقسط إن الله يحب المقسطين","(އެއީ) ގިނަގިނައިން ދޮގުބަސްތައް އަހާމީހުންނެވެ. ހަރާމް މުދާ ގިނައިން ކާމީހުންނެވެ. ފަހެ، އެއުރެން ކަލޭގެފާނުގެ އަރިހަށް އަތުވެއްޖެނަމަ އެއުރެންގެ މެދުގައި ހުކުމްކުރައްވާށެވެ! ނުވަތަ އެއުރެންގެ ކިބައިން އެނބުރިވަޑައިގަންނަވާށެވެ! އެއުރެންގެ ކިބައިން ކަލޭގެފާނު އެނބުރިވަޑައިގަތަސް އެއުރެންނަކަށް ކަލޭގެފާނަށް އެއްވެސް ކަމަކުން ގެއްލުމެއް ނުދެވޭނެތެވެ. އަދި ކަލޭގެފާނު ހުކުމްކުރައްވާނަމަ އެއުރެންގެ މެދުގައި ޢަދުލަށް ހުކުމްކުރައްވާށެވެ! ހަމަކަށަވަރުން، ޢަދުލަށް ހުކުމްކުރާ މީހުންދެކެ ﷲ ލޯބިވެވޮޑިގެންވެތެވެ.","",""],["₅ سورة المائدة","43","وَكَيۡفَ يُحَكِّمُونَكَ وَعِندَهُمُ ٱلتَّوۡرَىٰةُ فِيهَا حُكۡمُ ٱللَّهِ ثُمَّ يَتَوَلَّوۡنَ مِنۢ بَعۡدِ ذَٰلِكَۚ وَمَآ أُوْلَـٰٓئِكَ بِٱلۡمُؤۡمِنِينَ ٤٣","وكيف يحكمونك وعندهم التوراة فيها حكم الله ثم يتولون من بعد ذلك وما أولئك بالمؤمنين","އެއުރެންގެ އަތުގައި ތައުރާތު އޮވެ، އެ ތައުރާތުގައި ﷲގެ ހުކުމް ވަނިކޮށް، އެއުރެން ކަލޭގެފާނުގެ އަރިހުން ހުކުމަކަށް އެދެނީ ކޮންފަދަޔަކުންހޭ؟ ދެން އެއަށްފަހު، އެއުރެން (އެ ހުކުމަށް) ފުރަގަސްދެތެވެ. ފަހެ، އެއުރެން މުއުމިނުން ކަމުގައެއް ނުވެތެވެ.","",""],["₅ سورة المائدة","44","إِنَّآ أَنزَلۡنَا ٱلتَّوۡرَىٰةَ فِيهَا هُدٗى وَنُورٞۚ يَحۡكُمُ بِهَا ٱلنَّبِيُّونَ ٱلَّذِينَ أَسۡلَمُواْ لِلَّذِينَ هَادُواْ وَٱلرَّبَّـٰنِيُّونَ وَٱلۡأَحۡبَارُ بِمَا ٱسۡتُحۡفِظُواْ مِن كِتَٰبِ ٱللَّهِ وَكَانُواْ عَلَيۡهِ شُهَدَآءَۚ فَلَا تَخۡشَوُاْ ٱلنَّاسَ وَٱخۡشَوۡنِ وَلَا تَشۡتَرُواْ بِـَٔايَٰتِي ثَمَنٗا قَلِيلٗاۚ وَمَن لَّمۡ يَحۡكُم بِمَآ أَنزَلَ ٱللَّهُ فَأُوْلَـٰٓئِكَ هُمُ ٱلۡكَٰفِرُونَ ٤٤","إنا أنزلنا التوراة فيها هدى ونور يحكم بها النبيون الذين أسلموا للذين هادوا والربانيون والأحبار بما استحفظوا من كتاب الله وكانوا عليه شهداء فلا تخشوا الناس واخشون ولا تشتروا بآياتي ثمنا قليلا ومن لم يحكم بما أنزل الله فأولئك هم الكافرون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތައުރާތު ބާވައިލެއްވީމެވެ. އޭގައި ތެދުމަގާއި، އަލިކަންވެއެވެ. ކިޔަމަންތެރިވެގެން ތިއްބެވި ނަބިއްޔުންނާއި، ރައްބާނީން (އެބަހީ: ޔަހޫދީންގެ އަޅުވެރިން) ނާއި، ޔަހޫދީންގެ އިލްމުވެރިން، އެފޮތުން ޔަހޫދީންގެ މައްޗަށް ހުކުމްކުރައްވަތެވެ. (އެއީ) ﷲގެ ފޮތް ރައްކާތެރިކުރުމުގެ އަމާނަތެއުރެންނާ މަތިކުރައްވާފައި ވުމުގެ ސަބަބުންނެވެ. އަދި އެއުރެންނީ، އެފޮތުގެ މައްޗަށް ތިބި ހެކިވެރިންނެވެ. ފަހެ، ތިޔަބައިމީހުން މީސްތަކުންދެކެ ބިރުނުގަންނާށެވެ! ތިމަންރަސްކަލާނގެއަށް ބިރުގަންނާށެވެ! އަދި ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް ކުޑަ އަގެއް ތިޔަބައިމީހުން ނުގަންނާށެވެ! ﷲ ބާވައިލެއްވި ހުކުމުން ހުކުމް ނުކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެން އެއީ ހަމަ ކާފިރުންނެވެ.","",""],["₅ سورة المائدة","45","وَكَتَبۡنَا عَلَيۡهِمۡ فِيهَآ أَنَّ ٱلنَّفۡسَ بِٱلنَّفۡسِ وَٱلۡعَيۡنَ بِٱلۡعَيۡنِ وَٱلۡأَنفَ بِٱلۡأَنفِ وَٱلۡأُذُنَ بِٱلۡأُذُنِ وَٱلسِّنَّ بِٱلسِّنِّ وَٱلۡجُرُوحَ قِصَاصٞۚ فَمَن تَصَدَّقَ بِهِۦ فَهُوَ كَفَّارَةٞ لَّهُۥۚ وَمَن لَّمۡ يَحۡكُم بِمَآ أَنزَلَ ٱللَّهُ فَأُوْلَـٰٓئِكَ هُمُ ٱلظَّـٰلِمُونَ ٤٥","وكتبنا عليهم فيها أن النفس بالنفس والعين بالعين والأنف بالأنف والأذن بالأذن والسن بالسن والجروح قصاص فمن تصدق به فهو كفارة له ومن لم يحكم بما أنزل الله فأولئك هم الظالمون","އެ ތައުރާތުގައި އެއުރެންގެ މައްޗަށް ތިމަންރަސްކަލާނގެ (ގިސާސްގެ އުޞޫލު) ކަނޑައެޅުއްވީމެވެ. ހަމަކަށަވަރުން، ނަފްސަކަށް ނަފްސެކެވެ. ލޮލަކަށް ލޮލެކެވެ. ނޭފަތަކަށް ނޭފަތެކެވެ. ކަންފަތަކަށް ކަންފަތެކެވެ. ދަތަކަށް ދަތެކެވެ. ޒަޚަމް ތަކަކީ ގިސާސް ހުރި ކަމެކެވެ. ފަހެ، އެކަން މާފުކޮށްފި މީހާޔަށް އެއީ ކައްފާރާއެކެވެ. އަދި ﷲ ބާވައިލެއްވި ހުކުމުން ހުކުމް ނުކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެން އެއީ، ހަމަ އަނިޔާވެރިންނެވެ.","",""],["₅ سورة المائدة","46","وَقَفَّيۡنَا عَلَىٰٓ ءَاثَٰرِهِم بِعِيسَى ٱبۡنِ مَرۡيَمَ مُصَدِّقٗا لِّمَا بَيۡنَ يَدَيۡهِ مِنَ ٱلتَّوۡرَىٰةِۖ وَءَاتَيۡنَٰهُ ٱلۡإِنجِيلَ فِيهِ هُدٗى وَنُورٞ وَمُصَدِّقٗا لِّمَا بَيۡنَ يَدَيۡهِ مِنَ ٱلتَّوۡرَىٰةِ وَهُدٗى وَمَوۡعِظَةٗ لِّلۡمُتَّقِينَ ٤٦","وقفينا على آثارهم بعيسى ابن مريم مصدقا لما بين يديه من التوراة وآتيناه الإنجيل فيه هدى ونور ومصدقا لما بين يديه من التوراة وهدى وموعظة للمتقين","އަދި އެބޭކަލުންނާ ވިދިގެން ފަހަތުން މަރިޔަމްގެފާނުންގެ ދަރިކަލުން ޢީސާގެފާނު ތިމަންރަސްކަލާނގެ ފޮނުއްވީމެވެ. އެކަލޭގެފާނުންގެ ކުރިން (ބާވައިލައްވާފައިވާ) ތައުރާތު ގައިވާ ކަންތައް ތެދުކުރައްވަނިވި ބޭކަލެއްގެ ގޮތުގައެވެ. އަދި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް އިންޖީލު ދެއްވީމެވެ. އޭގައި ތެދުމަގާއި ނޫރު ވެއެވެ. އެއީ އޭގެކުރިން ބާވައިލައްވާފައިވާ ތައުރާތު ގައިވާ ކަންތައް ތެދުކުރަނިވި ގޮތުގައެވެ. އަދި ތަގުވާވެރިންނަށް ތެދުމަގާއި، ވައުޒެއް ކަމުގައެވެ.","",""],["₅ سورة المائدة","47","وَلۡيَحۡكُمۡ أَهۡلُ ٱلۡإِنجِيلِ بِمَآ أَنزَلَ ٱللَّهُ فِيهِۚ وَمَن لَّمۡ يَحۡكُم بِمَآ أَنزَلَ ٱللَّهُ فَأُوْلَـٰٓئِكَ هُمُ ٱلۡفَٰسِقُونَ ٤٧","وليحكم أهل الإنجيل بما أنزل الله فيه ومن لم يحكم بما أنزل الله فأولئك هم الفاسقون","އިންޖީލުގެ އަހުލުވެރިން އެ އިންޖީލުގައި ﷲ ބާވައިލައްވާފައިވާ ހުކުމުން ހުކުމްކުރާހުށިކަމެވެ! އަދި ﷲ ބާވައިލެއްވި ހުކުމުން ހުކުމް ނުކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެން އެއީ ހަމަ ފާސިގުންނެވެ.","",""],["₅ سورة المائدة","48","وَأَنزَلۡنَآ إِلَيۡكَ ٱلۡكِتَٰبَ بِٱلۡحَقِّ مُصَدِّقٗا لِّمَا بَيۡنَ يَدَيۡهِ مِنَ ٱلۡكِتَٰبِ وَمُهَيۡمِنًا عَلَيۡهِۖ فَٱحۡكُم بَيۡنَهُم بِمَآ أَنزَلَ ٱللَّهُۖ وَلَا تَتَّبِعۡ أَهۡوَآءَهُمۡ عَمَّا جَآءَكَ مِنَ ٱلۡحَقِّۚ لِكُلّٖ جَعَلۡنَا مِنكُمۡ شِرۡعَةٗ وَمِنۡهَاجٗاۚ وَلَوۡ شَآءَ ٱللَّهُ لَجَعَلَكُمۡ أُمَّةٗ وَٰحِدَةٗ وَلَٰكِن لِّيَبۡلُوَكُمۡ فِي مَآ ءَاتَىٰكُمۡۖ فَٱسۡتَبِقُواْ ٱلۡخَيۡرَٰتِۚ إِلَى ٱللَّهِ مَرۡجِعُكُمۡ جَمِيعٗا فَيُنَبِّئُكُم بِمَا كُنتُمۡ فِيهِ تَخۡتَلِفُونَ ٤٨","وأنزلنا إليك الكتاب بالحق مصدقا لما بين يديه من الكتاب ومهيمنا عليه فاحكم بينهم بما أنزل الله ولا تتبع أهواءهم عما جاءك من الحق لكل جعلنا منكم شرعة ومنهاجا ولو شاء الله لجعلكم أمة واحدة ولكن ليبلوكم في ما آتاكم فاستبقوا الخيرات إلى الله مرجعكم جميعا فينبئكم بما كنتم فيه تختلفون","އަދި ތިމަންރަސްކަލާނގެ ހައްގު ގޮތުގައި ކަލޭގެފާނަށް ފޮތް ބާވައިލެއްވީމެވެ. އޭގެކުރިން ބާވައިލެއްވި ފޮތްތަކުގައިވާ ތަކެތި ތެދުކުރަނިވި ގޮތުގައެވެ. އަދި އެފޮތްތަކުގެ މައްޗަށް ހެކިވަނިވި ފޮތެއް ކަމުގައެވެ. ފަހެ، ﷲ ބާވައިލައްވާފައިވާ ހުކުމުން، އެއުރެންގެ މެދުގައި، ކަލޭގެފާނު ހުކުމްކުރައްވާށެވެ! އަދި ކަލޭގެފާނުގެ އަރިހަށް އައިސްފައިވާ ހައްގު ގޮތާ ޚިލާފަށް އެއުރެންގެ އެދުންތަކަށް ކަލޭގެފާނު ތަބާ ވެވަޑައިނުގަންނަވާށެވެ! ތިޔަބައިމީހުންގެ ތެރެއިން ކޮންމެ ބަޔަކަށްމެ، ޝަރީޢަތަކާއި، ފާޅުވެގެންވާ މަގެއް، ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ. އަދި ﷲ އިރާދަކުރެއްވިނަމަ، ތިޔަބައިމީހުން އެއް އުއްމަތެއް ކަމުގައި ލައްވައިފީސްކަން ކަށަވަރެވެ. އެހެނެއްކަމަކު (ތިޔަބައިމީހުން އުއްމަތް ތަކަކަށް ބައިބައިކުރެއްވީ) ތިޔަބައިމީހުންނަށް ދެއްވި ޝަރީޢަތް ތަކާމެދު ތިޔަބައިމީހުން އިމްތިހާނުކުރެއްވުމަށެވެ. ފަހެ، ހެޔޮކަންތަކަށް ތިޔަބައިމީހުން ވާދަކުރާށެވެ! ތިޔަބައިމީހުން އެންމެން ރުޖޫއަ ވުންއޮތީ، ﷲގެ ހަޒުރަތަށެވެ. އޭރުން ތިޔަބައިމީހުން އެކަންކަމާމެދު ޚިލާފުވެ އުޅުނުކަންތަކުގެ ޚަބަރު ތިޔަބައިމީހުންނަށް އެކަލާނގެ އަންގަވާނެތެވެ.","",""],["₅ سورة المائدة","49","وَأَنِ ٱحۡكُم بَيۡنَهُم بِمَآ أَنزَلَ ٱللَّهُ وَلَا تَتَّبِعۡ أَهۡوَآءَهُمۡ وَٱحۡذَرۡهُمۡ أَن يَفۡتِنُوكَ عَنۢ بَعۡضِ مَآ أَنزَلَ ٱللَّهُ إِلَيۡكَۖ فَإِن تَوَلَّوۡاْ فَٱعۡلَمۡ أَنَّمَا يُرِيدُ ٱللَّهُ أَن يُصِيبَهُم بِبَعۡضِ ذُنُوبِهِمۡۗ وَإِنَّ كَثِيرٗا مِّنَ ٱلنَّاسِ لَفَٰسِقُونَ ٤٩","وأن احكم بينهم بما أنزل الله ولا تتبع أهواءهم واحذرهم أن يفتنوك عن بعض ما أنزل الله إليك فإن تولوا فاعلم أنما يريد الله أن يصيبهم ببعض ذنوبهم وإن كثيرا من الناس لفاسقون","އަދި ﷲ ބާވައިލައްވާފައިވާ ހުކުމުން އެއުރެންގެ މެދުގައި ކަލޭގެފާނު ހުކުމްކުރައްވާށެވެ! އަދި އެއުރެންގެ އަމިއްލަ އެދުންތަކަށް ކަލޭގެފާނު ތަބާ ވެވަޑައި ނުގަންނަވާށެވެ! އަދި ﷲ، ކަލޭގެފާނަށް ބާވައިލެއްވި ބައެއް އާޔަތުން ކަލޭގެފާނު އެއްކިބާކޮށްފާނެކަމަށް އެއުރެންނާމެދު ރައްކާތެރިވެ ވަޑައިގަންނަވާށެވެ! ފަހެ، އެއުރެން ފުރަގަސްދީފިނަމަ، ކަލޭގެފާނު ދެނެވަޑައިގަންނަވާށެވެ! ހަމަކަށަވަރުން، ﷲ އިރާދަކުރައްވަނީ، އެއުރެންގެ ބައެއް ފާފަތަކުގެ ސަބަބުން، އެއުރެންނަށްއުގޫބާތް ދެއްވުމަށެވެ. އަދި ހަމަކަށަވަރުން، މީސްތަކުންގެ ތެރެއިން ގިނަމީހުންނީ ފާސިގު ންކަން ކަށަވަރެވެ.","",""],["₅ سورة المائدة","50","أَفَحُكۡمَ ٱلۡجَٰهِلِيَّةِ يَبۡغُونَۚ وَمَنۡ أَحۡسَنُ مِنَ ٱللَّهِ حُكۡمٗا لِّقَوۡمٖ يُوقِنُونَ ٥٠","أفحكم الجاهلية يبغون ومن أحسن من الله حكما لقوم يوقنون","ފަހެ، އެއުރެން އެދެނީ ޖާހިލީ ޒަމާނުގެ ހުކުމް ހެއްޔެވެ؟ ޔަގީންކުރާ ބަޔަކަށް ﷲއަށްވުރެ ހުކުމްކުރެއްވުމަށް މޮޅީ ފަހެ ކާކުހެއްޔެވެ؟","",""],["₅ سورة المائدة","51","۞يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تَتَّخِذُواْ ٱلۡيَهُودَ وَٱلنَّصَٰرَىٰٓ أَوۡلِيَآءَۘ بَعۡضُهُمۡ أَوۡلِيَآءُ بَعۡضٖۚ وَمَن يَتَوَلَّهُم مِّنكُمۡ فَإِنَّهُۥ مِنۡهُمۡۗ إِنَّ ٱللَّهَ لَا يَهۡدِي ٱلۡقَوۡمَ ٱلظَّـٰلِمِينَ ٥١","يا أيها الذين آمنوا لا تتخذوا اليهود والنصارى أولياء بعضهم أولياء بعض ومن يتولهم منكم فإنه منهم إن الله لا يهدي القوم الظالمين","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ޔަހޫދީންނާއި، ނަސާރާ އިން (އެއީ) އެކުވެރިން ކަމުގައި ނުބަލާށެވެ! އެއުރެންގެ ތެރެއިން އެއްބަޔަކީ އަނެއްބަޔެއްގެ އެކުވެރިންނެވެ. ތިޔަބައިމީހުންގެ ތެރެއިން އެއުރެން އެކުވެރިން ކަމުގައި ބަލައިފިމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އެއީ، އެއުރެންގެ ތެރެއިންވާ މީހެކެވެ. ހަމަކަށަވަރުން، އަނިޔާވެރި ބަޔަކަށް ﷲ ތެދުމަގެއް ނުދައްކަވާނެތެވެ.","",""],["₅ سورة المائدة","52","فَتَرَى ٱلَّذِينَ فِي قُلُوبِهِم مَّرَضٞ يُسَٰرِعُونَ فِيهِمۡ يَقُولُونَ نَخۡشَىٰٓ أَن تُصِيبَنَا دَآئِرَةٞۚ فَعَسَى ٱللَّهُ أَن يَأۡتِيَ بِٱلۡفَتۡحِ أَوۡ أَمۡرٖ مِّنۡ عِندِهِۦ فَيُصۡبِحُواْ عَلَىٰ مَآ أَسَرُّواْ فِيٓ أَنفُسِهِمۡ نَٰدِمِينَ ٥٢","فترى الذين في قلوبهم مرض يسارعون فيهم يقولون نخشى أن تصيبنا دائرة فعسى الله أن يأتي بالفتح أو أمر من عنده فيصبحوا على ما أسروا في أنفسهم نادمين","ފަހެ، އެއުރެންގެ ހިތުގައި ބަލިމަޑުކަމެއް ހުންނަމީހުން (އެބަހީ: ޝައްކާއި ނިފާގުގެ ބަލިހުންނަ މީހުން) އެއުރެންގެ އެކުވެރިކަން ލިބިގަތުމަށް އަވަސްވެގަންނާތީ، ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނޫއެވެ. އެއުރެން ބުނެތެވެ. ތިމަންމެންނަށް މުސީބަތެއް ޖެހިދާނެކަމަށް ތިމަންމެން ބިރުގަނެތެވެ. ފަހެ، ﷲ ފަތަޙެއްވެސް ދެއްވައިފާނެތެވެ. ނުވަތަ އެކަލާނގެ ހަޒުރަތުން، އެހެން އަމުރު ފުޅެއްވެސް އަތުވެދާނެތެވެ. ފަހެ، އެހާރުން އެއުރެންގެ ހިތްތަކުގައި ވަންހަނާކުރި ކަންތަކުގެ މައްޗަށް ހިތާމަކުރާ ބަޔަކު ކަމުގައި އެއުރެން ވާނެތެވެ.","",""],["₅ سورة المائدة","53","وَيَقُولُ ٱلَّذِينَ ءَامَنُوٓاْ أَهَـٰٓؤُلَآءِ ٱلَّذِينَ أَقۡسَمُواْ بِٱللَّهِ جَهۡدَ أَيۡمَٰنِهِمۡ إِنَّهُمۡ لَمَعَكُمۡۚ حَبِطَتۡ أَعۡمَٰلُهُمۡ فَأَصۡبَحُواْ خَٰسِرِينَ ٥٣","ويقول الذين آمنوا أهؤلاء الذين أقسموا بالله جهد أيمانهم إنهم لمعكم حبطت أعمالهم فأصبحوا خاسرين","އީމާންވި މީހުން ބުނާނެތެވެ. ހަމަކަށަވަރުން، އެއުރެންތިބީ ތިޔަބައިމީހުންނާ އެކުގައިކަމަށް އެއުރެންނަށް ވެވުނުހައި ގަދައެއްކޮށް ﷲ ގަންދީ ހުވާކުރި ބަޔަކީ މިއީހެއްޔެވެ؟ އެއުރެންގެ ޢަމަލުތައްވަނީ ބާތިލު ވެފައެވެ. ދެން އެއުރެން ގެއްލި ހަލާކުވެގެންވާ ބަޔަކު ކަމުގައި ވެއްޖައޫއެވެ.","",""],["₅ سورة المائدة","54","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ مَن يَرۡتَدَّ مِنكُمۡ عَن دِينِهِۦ فَسَوۡفَ يَأۡتِي ٱللَّهُ بِقَوۡمٖ يُحِبُّهُمۡ وَيُحِبُّونَهُۥٓ أَذِلَّةٍ عَلَى ٱلۡمُؤۡمِنِينَ أَعِزَّةٍ عَلَى ٱلۡكَٰفِرِينَ يُجَٰهِدُونَ فِي سَبِيلِ ٱللَّهِ وَلَا يَخَافُونَ لَوۡمَةَ لَآئِمٖۚ ذَٰلِكَ فَضۡلُ ٱللَّهِ يُؤۡتِيهِ مَن يَشَآءُۚ وَٱللَّهُ وَٰسِعٌ عَلِيمٌ ٥٤","يا أيها الذين آمنوا من يرتد منكم عن دينه فسوف يأتي الله بقوم يحبهم ويحبونه أذلة على المؤمنين أعزة على الكافرين يجاهدون في سبيل الله ولا يخافون لومة لائم ذلك فضل الله يؤتيه من يشاء والله واسع عليم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ ތެރެއިން އެމީހެއްގެ ދީން ދޫކޮށް މުރުތައްދު ވާމީހާ (ދަންނާށެވެ!) ފަހެ، (އެއުރެންގެ ބަދަލުގައި) އެބަޔަކަށް އެކަލާނގެ ލޯބިވެވޮޑިގެންވާ، އަދި އެބަޔަކު އެކަލާނގެދެކެ ލޯބިވާ ބަޔަކު ﷲގެންނަވާނެތެވެ. އެއީ މުއުމިނުންގެ މައްޗަށް އޯގާވެރި، މަޑުމައިތިރި ބަޔެކެވެ. ކާފިރުންގެ މައްޗަށް ގަދަފަދަ ޢިއްޒަތް ތެރި ބަޔެކެވެ. ﷲގެ މަގުގައި އެއުރެން ޖިހާދުކުރާނެތެވެ. އަދި މަލާމާތްކުރާ މީހެއްގެ މަލާމާތަކަށް އެއުރެން ބިރެއް ނުގަންނާނެތެވެ. އެއީ ﷲގެ ފަޟްލު ވަންތަކަމެވެ. އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް އެކަން ދެއްވަތެވެ. ﷲއީ، ތަނަވަސްވަންތަ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","55","إِنَّمَا وَلِيُّكُمُ ٱللَّهُ وَرَسُولُهُۥ وَٱلَّذِينَ ءَامَنُواْ ٱلَّذِينَ يُقِيمُونَ ٱلصَّلَوٰةَ وَيُؤۡتُونَ ٱلزَّكَوٰةَ وَهُمۡ رَٰكِعُونَ ٥٥","إنما وليكم الله ورسوله والذين آمنوا الذين يقيمون الصلاة ويؤتون الزكاة وهم راكعون","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ އެހީތެރިޔަކީ ﷲއެވެ. އަދި އެކަލާނގެ ރަސޫލާއެވެ. އަދި އީމާން ވެގެންތިބި މީހުންނެވެ. އެއުރެންނީ ޚުޝޫޢު ގައިތިބެ ނަމާދުކޮށް، އަދި ޒަކާތް ދޭ މީހުންނެވެ.","",""],["₅ سورة المائدة","56","وَمَن يَتَوَلَّ ٱللَّهَ وَرَسُولَهُۥ وَٱلَّذِينَ ءَامَنُواْ فَإِنَّ حِزۡبَ ٱللَّهِ هُمُ ٱلۡغَٰلِبُونَ ٥٦","ومن يتول الله ورسوله والذين آمنوا فإن حزب الله هم الغالبون","ﷲއާއި، އެކަލާނގެ ރަސޫލާއާއި، އީމާން ވެގެންތިބި މީހުން އެއީ، އެހީތެރިންކަމުގައި ބަލައިފިމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ގަދަވާނެ ބަޔަކީ ހަމަ ﷲގެ ޖަމާއަތެވެ.","",""],["₅ سورة المائدة","57","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تَتَّخِذُواْ ٱلَّذِينَ ٱتَّخَذُواْ دِينَكُمۡ هُزُوٗا وَلَعِبٗا مِّنَ ٱلَّذِينَ أُوتُواْ ٱلۡكِتَٰبَ مِن قَبۡلِكُمۡ وَٱلۡكُفَّارَ أَوۡلِيَآءَۚ وَٱتَّقُواْ ٱللَّهَ إِن كُنتُم مُّؤۡمِنِينَ ٥٧","يا أيها الذين آمنوا لا تتخذوا الذين اتخذوا دينكم هزوا ولعبا من الذين أوتوا الكتاب من قبلكم والكفار أولياء واتقوا الله إن كنتم مؤمنين","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ ކުރިން ފޮތް ލިބުނު މީހުންގެ ތެރެއިން ތިޔަބައިމީހުންގެ ދީނަކީ ފުރައްސާރައެއް ކަމުގައްޔާއި، ކުޅިވަރެއް ކަމުގައި ހަދައިގެން އުޅުނު މީހުންނާއި، ކާފިރުން އެއީ، އެހީތެރިން ކަމުގައި ނުހަދާށެވެ! އަދި ތިޔަބައިމީހުންނީ، މުއުމިނުން ކަމުގައިވާނަމަ ﷲއަށް ތަގުވާވެރިވާށެވެ!","",""],["₅ سورة المائدة","58","وَإِذَا نَادَيۡتُمۡ إِلَى ٱلصَّلَوٰةِ ٱتَّخَذُوهَا هُزُوٗا وَلَعِبٗاۚ ذَٰلِكَ بِأَنَّهُمۡ قَوۡمٞ لَّا يَعۡقِلُونَ ٥٨","وإذا ناديتم إلى الصلاة اتخذوها هزوا ولعبا ذلك بأنهم قوم لا يعقلون","އަދި ތިޔަބައިމީހުން ނަމާދަށް ގޮވައިފިނަމަ އެކަމަކީ ފުރައްސާރައެއް ކަމުގައްޔާއި، ކުޅިވަރެއް ކަމުގައި އެއުރެން ހަދަތެވެ. އެއީ، އެއުރެންނަކީ ހަމަކަށަވަރުންވެސް ނުވިސްނޭބަޔަކު ކަމުގައިވާތީއެވެ.","",""],["₅ سورة المائدة","59","قُلۡ يَـٰٓأَهۡلَ ٱلۡكِتَٰبِ هَلۡ تَنقِمُونَ مِنَّآ إِلَّآ أَنۡ ءَامَنَّا بِٱللَّهِ وَمَآ أُنزِلَ إِلَيۡنَا وَمَآ أُنزِلَ مِن قَبۡلُ وَأَنَّ أَكۡثَرَكُمۡ فَٰسِقُونَ ٥٩","قل يا أهل الكتاب هل تنقمون منا إلا أن آمنا بالله وما أنزل إلينا وما أنزل من قبل وأن أكثركم فاسقون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ ފޮތުގެ އަހުލުވެރިންނޭވެ! ﷲ ތިމަންމެންނަށް ބާވައިލެއްވި ފޮތަށާއި، ކުރިން ބާވައިލެއްވި ފޮތްތަކަށް ތިމަންމެން އީމާންވާ ކަމާއި، ތިޔަބައިމީހުންކުރެ ގިނަމީހުންނަކީ ފާސިގުން ކަމުގައިވާކަން ފިޔަވައި އެހެންކަމަކާ ތިމަންމެންދެކެ ތިޔަބައިމީހުން ރުޅިއަރައި އިންކާރުކުރަމުހެއްޔެވެ؟","",""],["₅ سورة المائدة","60","قُلۡ هَلۡ أُنَبِّئُكُم بِشَرّٖ مِّن ذَٰلِكَ مَثُوبَةً عِندَ ٱللَّهِۚ مَن لَّعَنَهُ ٱللَّهُ وَغَضِبَ عَلَيۡهِ وَجَعَلَ مِنۡهُمُ ٱلۡقِرَدَةَ وَٱلۡخَنَازِيرَ وَعَبَدَ ٱلطَّـٰغُوتَۚ أُوْلَـٰٓئِكَ شَرّٞ مَّكَانٗا وَأَضَلُّ عَن سَوَآءِ ٱلسَّبِيلِ ٦٠","قل هل أنبئكم بشر من ذلك مثوبة عند الله من لعنه الله وغضب عليه وجعل منهم القردة والخنازير وعبد الطاغوت أولئك شر مكانا وأضل عن سواء السبيل","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲގެ ހަޒުރަތުގައި ޖަޒާދެއްވުމުގެ ގޮތުން އެއަށްވުރެ ނުބައިބަޔެއްގެ ވާހަކަ ތިޔަބައިމީހުންނަށް ތިމަންކަލޭގެފާނު އަންގަވައި ދެއްވަންހެއްޔެވެ؟ އެއުރެންނީ، ﷲ އެބަޔަކަށް ލައުނަތް ލައްވައި، އަދި އެބަޔެއްގެ މައްޗަށް ކޯފާލައްވައި އެބަޔެއްގެ ތެރެއިން ބަޔަކު ރާމާމަކުނުކަމުގައްޔާއި، އޫރުކަމުގައި ލައްވައި، އަދި އަނެއްބަޔަކު ޝައިތާނާއަށް އަޅުކަންކުރާ މީހުން ކަމުގައިލެއްވި މީހުންނެވެ. އެއުރެންނީ (ގިޔާމަތް ދުވަހުން) ތިބޭނެ ތަނުގެގޮތުން ނުބައިކަން ބޮޑުވެގެންވާ ބަޔެކެވެ. އަދި ހަމަ މަގުން އެއްކިބާވެ މަގުފުރެދުން ބޮޑު ބަޔެކެވެ.","",""],["₅ سورة المائدة","61","وَإِذَا جَآءُوكُمۡ قَالُوٓاْ ءَامَنَّا وَقَد دَّخَلُواْ بِٱلۡكُفۡرِ وَهُمۡ قَدۡ خَرَجُواْ بِهِۦۚ وَٱللَّهُ أَعۡلَمُ بِمَا كَانُواْ يَكۡتُمُونَ ٦١","وإذا جاءوكم قالوا آمنا وقد دخلوا بالكفر وهم قد خرجوا به والله أعلم بما كانوا يكتمون","އަދި އެއުރެން (އެބަހީ: ޔަހޫދީންގެ ތެރެއިން މުނާފިގުން) ތިޔަބައިމީހުންގެ ގާތަށް އަތުވެއްޖެނަމަ، ތިމަންމެން އީމާން ވެއްޖައީމުއޭ ބުނެތެވެ. އޭރު އެއުރެން (ތިޔަބައިމީހުންގެ ތެރެއަށް) ވަދެ އެތިބީ ކާފިރުކަމާއިގެންނެވެ. އަދި އެއުރެން ނުކުމެގެން ދިޔައީވެސް އެ ކާފިރުކަމާއިގެންނެވެ. އެއުރެން ވަންހަނާކޮށް އުޅުނުކަންތައް، ﷲ ދެނެވޮޑިގަތުން ބޮޑެވެ.","",""],["₅ سورة المائدة","62","وَتَرَىٰ كَثِيرٗا مِّنۡهُمۡ يُسَٰرِعُونَ فِي ٱلۡإِثۡمِ وَٱلۡعُدۡوَٰنِ وَأَكۡلِهِمُ ٱلسُّحۡتَۚ لَبِئۡسَ مَا كَانُواْ يَعۡمَلُونَ ٦٢","وترى كثيرا منهم يسارعون في الإثم والعدوان وأكلهم السحت لبئس ما كانوا يعملون","އަދި އޭގެތެރެއިން ގިނަމީހުން ފާފަވެރިވުމާއި، ދެކޮޅުވެރިވުމާއި، ހަރާމް މުދާ ކެއުމަށް އަވަސްވެގަންނަތަން، ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނޫއެވެ. އެއުރެން ކޮށްއުޅުނު ޢަމަލުތަކުގެ ނުބައިކަމާއެވެ!","",""],["₅ سورة المائدة","63","لَوۡلَا يَنۡهَىٰهُمُ ٱلرَّبَّـٰنِيُّونَ وَٱلۡأَحۡبَارُ عَن قَوۡلِهِمُ ٱلۡإِثۡمَ وَأَكۡلِهِمُ ٱلسُّحۡتَۚ لَبِئۡسَ مَا كَانُواْ يَصۡنَعُونَ ٦٣","لولا ينهاهم الربانيون والأحبار عن قولهم الإثم وأكلهم السحت لبئس ما كانوا يصنعون","އެއުރެން ފާފަވެރި ބަސްތައް ބުނުމާއި، ހަރާމް މުދާކެއުން ޔަހޫދީންގެ އަޅުވެރިންނާއި، އިލްމުވެރިން އެއުރެންނަށް މަނާކުރާނޭނަމަ ކޮންފަދަހެއްޔެވެ! އެއުރެން ކުރަމުންގެންދިޔަ ކަންތަކުގެ ނުބައިކަމާއެވެ!","",""],["₅ سورة المائدة","64","وَقَالَتِ ٱلۡيَهُودُ يَدُ ٱللَّهِ مَغۡلُولَةٌۚ غُلَّتۡ أَيۡدِيهِمۡ وَلُعِنُواْ بِمَا قَالُواْۘ بَلۡ يَدَاهُ مَبۡسُوطَتَانِ يُنفِقُ كَيۡفَ يَشَآءُۚ وَلَيَزِيدَنَّ كَثِيرٗا مِّنۡهُم مَّآ أُنزِلَ إِلَيۡكَ مِن رَّبِّكَ طُغۡيَٰنٗا وَكُفۡرٗاۚ وَأَلۡقَيۡنَا بَيۡنَهُمُ ٱلۡعَدَٰوَةَ وَٱلۡبَغۡضَآءَ إِلَىٰ يَوۡمِ ٱلۡقِيَٰمَةِۚ كُلَّمَآ أَوۡقَدُواْ نَارٗا لِّلۡحَرۡبِ أَطۡفَأَهَا ٱللَّهُۚ وَيَسۡعَوۡنَ فِي ٱلۡأَرۡضِ فَسَادٗاۚ وَٱللَّهُ لَا يُحِبُّ ٱلۡمُفۡسِدِينَ ٦٤","وقالت اليهود يد الله مغلولة غلت أيديهم ولعنوا بما قالوا بل يداه مبسوطتان ينفق كيف يشاء وليزيدن كثيرا منهم ما أنزل إليك من ربك طغيانا وكفرا وألقينا بينهم العداوة والبغضاء إلى يوم القيامة كلما أوقدوا نارا للحرب أطفأها الله ويسعون في الأرض فسادا والله لا يحب المفسدين","ޔަހޫދީން ބުނޫއެވެ. ﷲގެ އަތްޕުޅުވަނީ ބަންދުވެގެންނެވެ. (ޔަހޫދީން މިހެން ބުނީ ﷲ އަށް ދަހިކަން ނިސްބަތްކުރުމުގެ ގޮތުންނެވެ.) އެއުރެންގެ އަތްތައް ބަންދުވާށިއެވެ! އަދި އެއުރެން އެހެން ބުނުމުގެ ސަބަބުން އެއުރެންނަށް ލައުނަތް ލެއްވިއެވެ. އަދި ކިއެއްތަ! އެކަލާނގެ ދެ އަތްޕުޅުވަނީ ހުޅުވި ތަނަވަސްވެގެންނެވެ. އެކަލާނގެ އިރާދަކުރައްވާ ފަދަޔަކުން ހޭދަކުރައްވަތެވެ. ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ކަލޭގެފާނަށް ބާވައިލެއްވި ތަކެތި އޭގެތެރެއިން ގިނަމީހުންގައި ދެކޮޅުވެރިކަމާއި، ކާފިރު ކަން އިތުރުކުރާނެކަން ކަށަވަރެވެ. އަދި ގިޔާމަތަށް ދާނދެން އަދާވަތް ތެރިކަމާއި، ރުޅިވެރިކަން އެއުރެންގެ މެދުގައި ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ. އެއުރެން ހަނގުރާމައަށް އަލިފާންގަނޑެއް ރޯކޮށްފި ކޮންމެހިނދެއްގައި، ﷲ އެ އަލިފާންގަނޑު ނިއްވަވަތެވެ. އަދި ބިމުގައި ފަސާދަކުރުމުގެ ގޮތުން އެއުރެން މަސައްކަތް ކުރެތެވެ. ފަހެ، ފަސާދަކުރާ މީހުންދެކެ ﷲ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["₅ سورة المائدة","65","وَلَوۡ أَنَّ أَهۡلَ ٱلۡكِتَٰبِ ءَامَنُواْ وَٱتَّقَوۡاْ لَكَفَّرۡنَا عَنۡهُمۡ سَيِّـَٔاتِهِمۡ وَلَأَدۡخَلۡنَٰهُمۡ جَنَّـٰتِ ٱلنَّعِيمِ ٦٥","ولو أن أهل الكتاب آمنوا واتقوا لكفرنا عنهم سيئاتهم ولأدخلناهم جنات النعيم","ހަމަކަށަވަރުން، ފޮތުގެ އަހުލުވެރިން އީމާންވެ، ތަގުވާވެރިވީނަމަ، އެއުރެންގެ ކުށްތައް ތިމަންރަސްކަލާނގެ އެއުރެންގެ ކިބައިން ފުއްސެވީމުހެވެ. އަދި ނިއުމަތްގެ ސުވަރުގެތަކަށް ތިމަންރަސްކަލާނގެ އެއުރެން ވެއްދެވީމުހެވެ.","",""],["₅ سورة المائدة","66","وَلَوۡ أَنَّهُمۡ أَقَامُواْ ٱلتَّوۡرَىٰةَ وَٱلۡإِنجِيلَ وَمَآ أُنزِلَ إِلَيۡهِم مِّن رَّبِّهِمۡ لَأَكَلُواْ مِن فَوۡقِهِمۡ وَمِن تَحۡتِ أَرۡجُلِهِمۚ مِّنۡهُمۡ أُمَّةٞ مُّقۡتَصِدَةٞۖ وَكَثِيرٞ مِّنۡهُمۡ سَآءَ مَا يَعۡمَلُونَ ٦٦","ولو أنهم أقاموا التوراة والإنجيل وما أنزل إليهم من ربهم لأكلوا من فوقهم ومن تحت أرجلهم منهم أمة مقتصدة وكثير منهم ساء ما يعملون","އަދި އެއުރެން ތައުރާތާއި، އިންޖީލާއި، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އެއުރެންނަށް ބާވައިލެއްވި ފޮތުގެ (އެބަހީ: ގުރްއާންގެ) ހުކުމް ގާއިމުކުރިނަމަ، އެއުރެންގެ މަތިންނާއި، އެއުރެންގެ ފައިދަށުން އެއުރެންނަށް ރިޒްގު ލިބުނީހެވެ. އެއުރެންގެ ތެރެއިން މެދުމިން ބަޔަކުވެސް ވެއެވެ. ނަމަވެސް އޭގެތެރެއިން ގިނަމީހުން ކުޅަ ޢަމަލުތައް ހާދަހާ ނުބައިވެގެންވެއެވެ.","",""],["₅ سورة المائدة","67","۞يَـٰٓأَيُّهَا ٱلرَّسُولُ بَلِّغۡ مَآ أُنزِلَ إِلَيۡكَ مِن رَّبِّكَۖ وَإِن لَّمۡ تَفۡعَلۡ فَمَا بَلَّغۡتَ رِسَالَتَهُۥۚ وَٱللَّهُ يَعۡصِمُكَ مِنَ ٱلنَّاسِۗ إِنَّ ٱللَّهَ لَا يَهۡدِي ٱلۡقَوۡمَ ٱلۡكَٰفِرِينَ ٦٧","يا أيها الرسول بلغ ما أنزل إليك من ربك وإن لم تفعل فما بلغت رسالته والله يعصمك من الناس إن الله لا يهدي القوم الكافرين","އޭ ރަސޫލާއެވެ! ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ކަލޭގެފާނަށް ބާވައިލެއްވި އާޔަތްތައް ކަލޭގެފާނު އިއްވަވާށެވެ! އަދި ކަލޭގެފާނު އެކަން ނުކުރެއްވިނަމަ، ކަލޭގެފާނު އެކަލާނގެ ރިސާލަތް އިއްވެވިކަމަކަށް ނުވާނެއެވެ. އަދި ﷲ މީސްތަކުންގެ ކިބައިން ކަލޭގެފާނު ރައްކާތެރި ކުރައްވާނެތެވެ. ހަމަކަށަވަރުން، ކާފިރުވި މީސްތަކުންނަށް ﷲ ތެދުމަގެއް ނުދައްކަވާނެތެވެ.","",""],["₅ سورة المائدة","68","قُلۡ يَـٰٓأَهۡلَ ٱلۡكِتَٰبِ لَسۡتُمۡ عَلَىٰ شَيۡءٍ حَتَّىٰ تُقِيمُواْ ٱلتَّوۡرَىٰةَ وَٱلۡإِنجِيلَ وَمَآ أُنزِلَ إِلَيۡكُم مِّن رَّبِّكُمۡۗ وَلَيَزِيدَنَّ كَثِيرٗا مِّنۡهُم مَّآ أُنزِلَ إِلَيۡكَ مِن رَّبِّكَ طُغۡيَٰنٗا وَكُفۡرٗاۖ فَلَا تَأۡسَ عَلَى ٱلۡقَوۡمِ ٱلۡكَٰفِرِينَ ٦٨","قل يا أهل الكتاب لستم على شيء حتى تقيموا التوراة والإنجيل وما أنزل إليكم من ربكم وليزيدن كثيرا منهم ما أنزل إليك من ربك طغيانا وكفرا فلا تأس على القوم الكافرين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ ފޮތުގެ އަހުލުވެރިންނޭވެ! ތިޔަބައިމީހުން ތައުރާތާއި، އިންޖީލާއި، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ތިޔަބައިމީހުންނަށް ބާވައިލެއްވިފޮތުގެ (އެބަހީ: ގުރްއާންގެ) ހުކުމް ގާއިމު ކޮށްފުމަށްދާނދެން ތިޔަބައިމީހުން ތެދުމަގެއްގައި ތިބިބަޔަކު ކަމުގައި ނުވަމުއެވެ. ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ކަލޭގެފާނަށް ބާވައިލެއްވި ތަކެތި، އޭގެތެރެއިން ގިނަމީހުންގައި ދެކޮޅުވެރިކަމާއި، ކާފިރު ކަން އިތުރުކުރާނެކަން ކަށަވަރެވެ. ފަހެ، ކާފިރުވި މީސްތަކުންގެ މައްޗަށް ކަލޭގެފާނު ހިތާމަ ނުކުރައްވާށެވެ!","",""],["₅ سورة المائدة","69","إِنَّ ٱلَّذِينَ ءَامَنُواْ وَٱلَّذِينَ هَادُواْ وَٱلصَّـٰبِـُٔونَ وَٱلنَّصَٰرَىٰ مَنۡ ءَامَنَ بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِ وَعَمِلَ صَٰلِحٗا فَلَا خَوۡفٌ عَلَيۡهِمۡ وَلَا هُمۡ يَحۡزَنُونَ ٦٩","إن الذين آمنوا والذين هادوا والصابئون والنصارى من آمن بالله واليوم الآخر وعمل صالحا فلا خوف عليهم ولا هم يحزنون","ހަމަކަށަވަރުން، އީމާންވި މީހުންނާއި، ޔަހޫދީން ކަމުގައިވި މީހުންނާއި، ޞާބިއްނާއި، ނަސާރާ އިންގެ ތެރެއިން ﷲއަށާއި، އާޚިރަތް ދުވަހަށް އީމާންވެ، ހެޔޮ ޢަމަލުކުޅަމީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެންގެ މައްޗަކަށް އެއްވެސް ބިރެއްނެތެވެ. އަދި އެއުރެންނީ، ހިތާމަކުރާނޭ ބަޔަކު ކަމުގައިވެސް ނުމެވޭމެއެވެ.","",""],["₅ سورة المائدة","70","لَقَدۡ أَخَذۡنَا مِيثَٰقَ بَنِيٓ إِسۡرَـٰٓءِيلَ وَأَرۡسَلۡنَآ إِلَيۡهِمۡ رُسُلٗاۖ كُلَّمَا جَآءَهُمۡ رَسُولُۢ بِمَا لَا تَهۡوَىٰٓ أَنفُسُهُمۡ فَرِيقٗا كَذَّبُواْ وَفَرِيقٗا يَقۡتُلُونَ ٧٠","لقد أخذنا ميثاق بني إسرائيل وأرسلنا إليهم رسلا كلما جاءهم رسول بما لا تهوى أنفسهم فريقا كذبوا وفريقا يقتلون","ހަމަކަށަވަރުން، އިސްރާއީލުގެދަރިންގެ ކަށަވަރުވެގެންވާ އަހުދު ތިމަންރަސްކަލާނގެ ހިއްޕެވީމެވެ. އަދި އެއުރެންގެ ގާތަށް ރަސޫލުންތަކެއް ފޮނުއްވީމެވެ. އެއުރެންގެ ހިތް ނޭދޭގޮތަކާއިގެން، އެއުރެންގެ ގާތަށް ރަސޫލަކު ވަޑައިގެންފި ކޮންމެ ހިނދެއްގައި، އެއުރެން އޭގެތެރެއިން ބައެއް ރަސޫލުންގެ ބަސްފުޅު ދޮގުކުރެތެވެ. އަދި އެއުރެން އަނެއްބައި ރަސޫލުން ގަތުލުކުރެތެވެ.","",""],["₅ سورة المائدة","71","وَحَسِبُوٓاْ أَلَّا تَكُونَ فِتۡنَةٞ فَعَمُواْ وَصَمُّواْ ثُمَّ تَابَ ٱللَّهُ عَلَيۡهِمۡ ثُمَّ عَمُواْ وَصَمُّواْ كَثِيرٞ مِّنۡهُمۡۚ وَٱللَّهُ بَصِيرُۢ بِمَا يَعۡمَلُونَ ٧١","وحسبوا ألا تكون فتنة فعموا وصموا ثم تاب الله عليهم ثم عموا وصموا كثير منهم والله بصير بما يعملون","އެއުރެންނަށް އިމްތިހާނެއް ނާންނާނެކަމަށް، އެއުރެން ހީކުޅައޫއެވެ. ފަހެ، (އެކަމުގެ ސަބަބުން ހައްގާމެދު) އެއުރެން ކަނުވެގެންފޫއެވެ. އަދި ބީރުވެގެންފޫއެވެ. ދެން ﷲ، އެއުރެންގެ މައްޗަށް ތައުބާ ލެއްވިއެވެ. ދެންވެސް އެއުރެންގެ ތެރެއިން ގިނަބަޔަކު ކަނުވެގެންފޫއެވެ. އަދި ބީރުވެގެންފޫއެވެ. ﷲއީ، އެއުރެންކުރާ ކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","72","لَقَدۡ كَفَرَ ٱلَّذِينَ قَالُوٓاْ إِنَّ ٱللَّهَ هُوَ ٱلۡمَسِيحُ ٱبۡنُ مَرۡيَمَۖ وَقَالَ ٱلۡمَسِيحُ يَٰبَنِيٓ إِسۡرَـٰٓءِيلَ ٱعۡبُدُواْ ٱللَّهَ رَبِّي وَرَبَّكُمۡۖ إِنَّهُۥ مَن يُشۡرِكۡ بِٱللَّهِ فَقَدۡ حَرَّمَ ٱللَّهُ عَلَيۡهِ ٱلۡجَنَّةَ وَمَأۡوَىٰهُ ٱلنَّارُۖ وَمَا لِلظَّـٰلِمِينَ مِنۡ أَنصَارٖ ٧٢","لقد كفر الذين قالوا إن الله هو المسيح ابن مريم وقال المسيح يا بني إسرائيل اعبدوا الله ربي وربكم إنه من يشرك بالله فقد حرم الله عليه الجنة ومأواه النار وما للظالمين من أنصار","ހަމަކަށަވަރުން، ﷲއީ، މަރިޔަމްގެފާނުގެ ދަރިކަލުން އަލްމަސީޙު (ޢީސާގެފާނު) ކަމަށް ބުނި މީހުން ކާފިރު ވެއްޖެކަން ކަށަވަރެވެ. އަދި އަލްމަސީޙު ވިދާޅުވިއެވެ. އޭ އިސްރާއީލުގެދަރިންނޭވެ! އަހުރެންގެ ވެރިރަސްކަލާނގެ، އަދި ތިޔަބައިމީހުންގެވެސް ވެރިރަސްކަލާނގެ ކަމުގައިވާ ﷲއަށް ތިޔަބައިމީހުން އަޅުކަން ކުރާށެވެ! ހަމަކަށަވަރުން ﷲއަށް ޝަރީކުކުރާ މީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲ، އެމީހާގެ މައްޗަށް ސުވަރުގެ ހަރާމްކުރެއްވިއެވެ. އަދި އެމީހަކު އުޅޭނެތަނަކީ ނަރަކައެވެ. އަދި އަނިޔާވެރިންނަށް (އެބަހީ: ޝަރީކުކުޅަ މީހުންނަށް) ނަސްރު ދޭނޭ އެއްވެސް ބަޔަކު ނުވެއެވެ.","",""],["₅ سورة المائدة","73","لَّقَدۡ كَفَرَ ٱلَّذِينَ قَالُوٓاْ إِنَّ ٱللَّهَ ثَالِثُ ثَلَٰثَةٖۘ وَمَا مِنۡ إِلَٰهٍ إِلَّآ إِلَٰهٞ وَٰحِدٞۚ وَإِن لَّمۡ يَنتَهُواْ عَمَّا يَقُولُونَ لَيَمَسَّنَّ ٱلَّذِينَ كَفَرُواْ مِنۡهُمۡ عَذَابٌ أَلِيمٌ ٧٣","لقد كفر الذين قالوا إن الله ثالث ثلاثة وما من إله إلا إله واحد وإن لم ينتهوا عما يقولون ليمسن الذين كفروا منهم عذاب أليم","ހަމަކަށަވަރުން، ﷲއީ، ތިން އިލާހު ންކުރެ އިލާހު އެކޭ ބުނި މީހުން ކާފިރު ވެއްޖެކަން ކަށަވަރެވެ. އެއްކައުވަންތަ އިލާހު މެނުވީ، އެހެން އިލާހަކު ނުވެއެވެ. އެއުރެން އެބުނާ ބުނުން ހުއްޓާނުލިނަމަ، ހަމަކަށަވަރުން، އެއުރެންގެ ތެރެއިން ކާފިރުވި މީހުންނަށް ވޭންދެނިވި އަޒާބު ލިބޭނެކަން ކަށަވަރެވެ.","",""],["₅ سورة المائدة","74","أَفَلَا يَتُوبُونَ إِلَى ٱللَّهِ وَيَسۡتَغۡفِرُونَهُۥۚ وَٱللَّهُ غَفُورٞ رَّحِيمٞ ٧٤","أفلا يتوبون إلى الله ويستغفرونه والله غفور رحيم","ފަހެ، އެއުރެން ﷲއަށް ތައުބާ ނުވަނީހެއްޔެވެ؟ އަދި ފާފަފުއްސެވުން އެދި އެކަލާނގެ ހަޒުރަތަށް ނުދަންނަވަނީ ހެއްޔެވެ؟ ފަހެ، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","75","مَّا ٱلۡمَسِيحُ ٱبۡنُ مَرۡيَمَ إِلَّا رَسُولٞ قَدۡ خَلَتۡ مِن قَبۡلِهِ ٱلرُّسُلُ وَأُمُّهُۥ صِدِّيقَةٞۖ كَانَا يَأۡكُلَانِ ٱلطَّعَامَۗ ٱنظُرۡ كَيۡفَ نُبَيِّنُ لَهُمُ ٱلۡأٓيَٰتِ ثُمَّ ٱنظُرۡ أَنَّىٰ يُؤۡفَكُونَ ٧٥","ما المسيح ابن مريم إلا رسول قد خلت من قبله الرسل وأمه صديقة كانا يأكلان الطعام انظر كيف نبين لهم الآيات ثم انظر أنى يؤفكون","ރަސޫލަކު ކަމުގައި މެނުވީ މަރިޔަމްގެފާނުންގެ ދަރިކަލުން އަލްމަސީޙު ނުވެއެވެ. ހަމަކަށަވަރުން، އެކަލޭގެފާނުގެ ކުރިންވެސް ރަސޫލުން އިސްވެގޮސްފައިވެއެވެ. އެކަލޭގެފާނުގެ މައިކަނބަލުންނަކީ ތެދުވެރި ބޭކަނބަލެކެވެ. އެ ދެމައިކަނބަލުން (އެހެނިހެން މީހުންފަދައިން) ކާތަކެތި ފަރިއްކުޅުއްވައި އުޅުއްވިއެވެ. ތިމަންރަސްކަލާނގެ އެއުރެންނަށް އާޔަތްތައް (އެބަހީ: ހެކިތައް) ބަޔާން ކޮށްދެއްވަނީ ކޮންފަދަޔަކުންކަން ދެކޭށެވެ! ދެން އެއުރެން (ހައްގުގެމަގުން) އެއްކިބާވަނީ ކޮންފަދަޔަކުންކަން ދެކޭށެވެ!","",""],["₅ سورة المائدة","76","قُلۡ أَتَعۡبُدُونَ مِن دُونِ ٱللَّهِ مَا لَا يَمۡلِكُ لَكُمۡ ضَرّٗا وَلَا نَفۡعٗاۚ وَٱللَّهُ هُوَ ٱلسَّمِيعُ ٱلۡعَلِيمُ ٧٦","قل أتعبدون من دون الله ما لا يملك لكم ضرا ولا نفعا والله هو السميع العليم","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންނަށް ގެއްލުމެއް ދިނުންވިޔަސް، މަންފާއެއް ދިނުންވިޔަސް، މިލްކުވެގެންނުވާ ތަކެއްޗަށް، ﷲ ފިޔަވައި ތިޔަބައިމީހުން އަޅުކަންކުރަނީ ހެއްޔެވެ؟ ފަހެ، ﷲއީ، މޮޅަށް އައްސަވާ ވޮޑިގެންވާ މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","77","قُلۡ يَـٰٓأَهۡلَ ٱلۡكِتَٰبِ لَا تَغۡلُواْ فِي دِينِكُمۡ غَيۡرَ ٱلۡحَقِّ وَلَا تَتَّبِعُوٓاْ أَهۡوَآءَ قَوۡمٖ قَدۡ ضَلُّواْ مِن قَبۡلُ وَأَضَلُّواْ كَثِيرٗا وَضَلُّواْ عَن سَوَآءِ ٱلسَّبِيلِ ٧٧","قل يا أهل الكتاب لا تغلوا في دينكم غير الحق ولا تتبعوا أهواء قوم قد ضلوا من قبل وأضلوا كثيرا وضلوا عن سواء السبيل","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ ފޮތުގެ އަހުލުވެރިންނޭވެ! ތިޔަބައިމީހުންގެ ދީނާމެދު ހައްގު ނޫންގޮތުގައި ތިޔަބައިމީހުން ހައްދުފަހަނަޅައި ނުދާށެވެ! އަދި ހަމަކަށަވަރުން، ކުރިން މަގުފުރެދިފައިވާ، އަދި ގިނަބަޔަކު މަގުފުރައްދާފައިވާ، އަދި ހަމަމަގުން އެއްކިބާވެ، މަގުފުރެދިފައިވާ ބަޔެއްގެ އެދުންތަކަށް، ތިޔަބައިމީހުން ތަބާ ނުވާށެވެ!","",""],["₅ سورة المائدة","78","لُعِنَ ٱلَّذِينَ كَفَرُواْ مِنۢ بَنِيٓ إِسۡرَـٰٓءِيلَ عَلَىٰ لِسَانِ دَاوُۥدَ وَعِيسَى ٱبۡنِ مَرۡيَمَۚ ذَٰلِكَ بِمَا عَصَواْ وَّكَانُواْ يَعۡتَدُونَ ٧٨","لعن الذين كفروا من بني إسرائيل على لسان داوود وعيسى ابن مريم ذلك بما عصوا وكانوا يعتدون","އިސްރާއީލުގެދަރިންގެ ތެރެއިން، ކާފިރުވި މީހުންނަށް، ދާވޫދުގެފާނާއި، މަރިޔަމްގެފާނުގެ ދަރިކަލުން ޢީސާގެފާނުގެ ދޫފުޅުމަތިން ލައުނަތް ލައްވާފައިވެއެވެ. އެއީ އެއުރެން އުރެދުނު ކަމަށްޓަކައެވެ. އަދި އުރެދުމުގައި ހައްދުފަހަނަޅައިދާކަމުގައި އެއުރެން ވީކަމަށްޓަކައެވެ.","",""],["₅ سورة المائدة","79","كَانُواْ لَا يَتَنَاهَوۡنَ عَن مُّنكَرٖ فَعَلُوهُۚ لَبِئۡسَ مَا كَانُواْ يَفۡعَلُونَ ٧٩","كانوا لا يتناهون عن منكر فعلوه لبئس ما كانوا يفعلون","އެއުރެންކުޅަ ނުބައިކަންތައް، އެއްބަޔަކު އަނެއްބަޔަކަށް ނަހީކޮށެއް ނުއުޅެތެވެ. އެއުރެން ކޮށްއުޅުނު ކަންތަކުގެ ނުބައިކަމާއެވެ!","",""],["₅ سورة المائدة","80","تَرَىٰ كَثِيرٗا مِّنۡهُمۡ يَتَوَلَّوۡنَ ٱلَّذِينَ كَفَرُواْۚ لَبِئۡسَ مَا قَدَّمَتۡ لَهُمۡ أَنفُسُهُمۡ أَن سَخِطَ ٱللَّهُ عَلَيۡهِمۡ وَفِي ٱلۡعَذَابِ هُمۡ خَٰلِدُونَ ٨٠","ترى كثيرا منهم يتولون الذين كفروا لبئس ما قدمت لهم أنفسهم أن سخط الله عليهم وفي العذاب هم خالدون","އޭގެތެރެއިން ގިނަމީހުން ކާފިރުވި މީހުންގެ އެކުވެރިކަން ލިބިގަންނާތީ ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނޫއެވެ. އެއުރެންގެ ނަފްސުތައް، އެއުރެންނަށްޓަކައި، ކުރިމަތިކުޅަ ކަންތަކުގެ ނުބައިކަމާއެވެ! އެއީ ﷲ، އެއުރެންގެ މައްޗަށް ކޯފާލެއްވުމެވެ. އަދި އެއުރެންނީ އަޒާބުގެ ތެރޭގައި ދެމިތިބޭނޭ ބަޔަކު ކަމުގައިވުމެވެ.","",""],["₅ سورة المائدة","81","وَلَوۡ كَانُواْ يُؤۡمِنُونَ بِٱللَّهِ وَٱلنَّبِيِّ وَمَآ أُنزِلَ إِلَيۡهِ مَا ٱتَّخَذُوهُمۡ أَوۡلِيَآءَ وَلَٰكِنَّ كَثِيرٗا مِّنۡهُمۡ فَٰسِقُونَ ٨١","ولو كانوا يؤمنون بالله والنبي وما أنزل إليه ما اتخذوهم أولياء ولكن كثيرا منهم فاسقون","އެއުރެން ﷲއަށާއި، ނަބިއްޔާއަށާއި، އެކަލޭގެފާނަށް ބާވައިލެއްވި ފޮތަށް އީމާންވާ ކަމުގައިވީނަމަ، އެ ކާފިރުންނީ، އެކުވެރިން ކަމުގައެއް ނުހިފީހެވެ. އެހެނެއްކަމަކު އޭގެތެރެއިން ގިނަމީހުންނީ ފާސިގުންނެވެ.","",""],["₅ سورة المائدة","82","۞لَتَجِدَنَّ أَشَدَّ ٱلنَّاسِ عَدَٰوَةٗ لِّلَّذِينَ ءَامَنُواْ ٱلۡيَهُودَ وَٱلَّذِينَ أَشۡرَكُواْۖ وَلَتَجِدَنَّ أَقۡرَبَهُم مَّوَدَّةٗ لِّلَّذِينَ ءَامَنُواْ ٱلَّذِينَ قَالُوٓاْ إِنَّا نَصَٰرَىٰۚ ذَٰلِكَ بِأَنَّ مِنۡهُمۡ قِسِّيسِينَ وَرُهۡبَانٗا وَأَنَّهُمۡ لَا يَسۡتَكۡبِرُونَ ٨٢","لتجدن أشد الناس عداوة للذين آمنوا اليهود والذين أشركوا ولتجدن أقربهم مودة للذين آمنوا الذين قالوا إنا نصارى ذلك بأن منهم قسيسين ورهبانا وأنهم لا يستكبرون","އީމާންވި މީހުންނަށް މީސްތަކުންކުރެ، އަދާވަތް ތެރިކަން އެންމެބޮޑު ބަޔަކީ، ޔަހޫދީންނާއި، އަދި ޝަރީކުކުޅަ މީހުން ކަމުގައި ހަމަކަށަވަރުން، ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނޫއެވެ. އަދި އީމާންވި މީހުންނަށް، މީސްތަކުންކުރެ ރަހުމަތް ތެރިކަމުގެ ގޮތުން އެންމެ ގާތްބަޔަކީ، ތިމަންމެންނީ ނަސާރާ އިންނޭ ބުނި މީހުން ކަމުގައި ހަމަކަށަވަރުން، ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނޫއެވެ. އެއީ ހަމަކަށަވަރުން، އެއުރެންގެ ތެރެއިން ފާދިރީންނާއި، އަޅުވެރި ރާހިބުން ވާކަމަށްޓަކައެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެންނީ ބޮޑާވެނުގަންނަ ބަޔަކު ކަމުގައިވެސް ވާކަމަށްޓަކައެވެ.","",""],["₅ سورة المائدة","83","وَإِذَا سَمِعُواْ مَآ أُنزِلَ إِلَى ٱلرَّسُولِ تَرَىٰٓ أَعۡيُنَهُمۡ تَفِيضُ مِنَ ٱلدَّمۡعِ مِمَّا عَرَفُواْ مِنَ ٱلۡحَقِّۖ يَقُولُونَ رَبَّنَآ ءَامَنَّا فَٱكۡتُبۡنَا مَعَ ٱلشَّـٰهِدِينَ ٨٣","وإذا سمعوا ما أنزل إلى الرسول ترى أعينهم تفيض من الدمع مما عرفوا من الحق يقولون ربنا آمنا فاكتبنا مع الشاهدين","އަދި ރަސޫލާއަށް ބާވައިލެއްވި އާޔަތްތައް، އެއުރެން އަޑުއެހި ހިނދު، އެއުރެންނަށް ހައްގު ގޮތް އެނގުމުގެ ސަބަބުން، އެއުރެންގެ ލޯތައް ކަރުނައިންފުރި އޮހޭތަން، ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނޫއެވެ. އެއުރެން ބުނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! އަޅަމެން އީމާން ވެއްޖައީމުއެވެ. ފަހެ، ހެކިވާ މީހުންގެ ތެރޭގައި އަޅަމެން ލިޔުއްވާނދޭވެ!","",""],["₅ سورة المائدة","84","وَمَا لَنَا لَا نُؤۡمِنُ بِٱللَّهِ وَمَا جَآءَنَا مِنَ ٱلۡحَقِّ وَنَطۡمَعُ أَن يُدۡخِلَنَا رَبُّنَا مَعَ ٱلۡقَوۡمِ ٱلصَّـٰلِحِينَ ٨٤","وما لنا لا نؤمن بالله وما جاءنا من الحق ونطمع أن يدخلنا ربنا مع القوم الصالحين","އަދި ﷲއަށާއި، ތިމަންމެންގެ ގާތަށްއައި ހައްގު ގޮތަށް، ތިމަންމެން އީމާން ނުވާންވީ، އަދި ތިމަންމެންގެ ވެރިރަސްކަލާނގެ ސާލިހު އަޅުންގެ ތެރެޔަށް ތިމަންމެން ވެއްދެވުމަށް އެދުންވެރި ނުވާންވީ ކީއްވެގެން ހެއްޔެވެ؟","",""],["₅ سورة المائدة","85","فَأَثَٰبَهُمُ ٱللَّهُ بِمَا قَالُواْ جَنَّـٰتٖ تَجۡرِي مِن تَحۡتِهَا ٱلۡأَنۡهَٰرُ خَٰلِدِينَ فِيهَاۚ وَذَٰلِكَ جَزَآءُ ٱلۡمُحۡسِنِينَ ٨٥","فأثابهم الله بما قالوا جنات تجري من تحتها الأنهار خالدين فيها وذلك جزاء المحسنين","ދެން އެއުރެން ބުނި ބަސްތަކުގެ ސަބަބުން ޖަޒާއަކަށް، އެތާނގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތައް އެއުރެންނަށް ﷲ ދެއްވިއެވެ. އެތާނގައި އެއުރެން ދެމިތިބޭ ޙާލު ގައެވެ. އެއީ އިހްސާން ތެރިންގެ ޖަޒާއެވެ.","",""],["₅ سورة المائدة","86","وَٱلَّذِينَ كَفَرُواْ وَكَذَّبُواْ بِـَٔايَٰتِنَآ أُوْلَـٰٓئِكَ أَصۡحَٰبُ ٱلۡجَحِيمِ ٨٦","والذين كفروا وكذبوا بآياتنا أولئك أصحاب الجحيم","އަދި ކާފިރުވެ، ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުޅަ މީހުން އެއީ، ނަރަކައިގެ އަހުލުވެރިންނެވެ.","",""],["₅ سورة المائدة","87","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تُحَرِّمُواْ طَيِّبَٰتِ مَآ أَحَلَّ ٱللَّهُ لَكُمۡ وَلَا تَعۡتَدُوٓاْۚ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلۡمُعۡتَدِينَ ٨٧","يا أيها الذين آمنوا لا تحرموا طيبات ما أحل الله لكم ولا تعتدوا إن الله لا يحب المعتدين","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންނަށްޓަކައި، ﷲ، ހަލާލުކުރައްވާފައިވާ ރަނގަޅު ކަންތަކާއި ތަކެތި، ތިޔަބައިމީހުން ހަރާމް ނުކުރާށެވެ! އަދި ތިޔަބައިމީހުން ހައްދުފަހަނަޅައި ނުދާށެވެ! ހަމަކަށަވަރުން، ހައްދުފަހަނަޅައިދާ މީހުންދެކެ ﷲ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["₅ سورة المائدة","88","وَكُلُواْ مِمَّا رَزَقَكُمُ ٱللَّهُ حَلَٰلٗا طَيِّبٗاۚ وَٱتَّقُواْ ٱللَّهَ ٱلَّذِيٓ أَنتُم بِهِۦ مُؤۡمِنُونَ ٨٨","وكلوا مما رزقكم الله حلالا طيبا واتقوا الله الذي أنتم به مؤمنون","އަދި ﷲ، ތިޔަބައިމީހުންނަށް ދެއްވި ތަކެތީގެ ތެރެއިން، ހަލާލު ރަނގަޅު ތަކެތި ކައިއުޅޭށެވެ! އަދި ތިޔަބައިމީހުން، އެކަލާނގެއަށް އީމާން ވެގެންތިބި ﷲއަށް، ތިޔަބައިމީހުން ތަގުވާވެރިވާށެވެ!","",""],["₅ سورة المائدة","89","لَا يُؤَاخِذُكُمُ ٱللَّهُ بِٱللَّغۡوِ فِيٓ أَيۡمَٰنِكُمۡ وَلَٰكِن يُؤَاخِذُكُم بِمَا عَقَّدتُّمُ ٱلۡأَيۡمَٰنَۖ فَكَفَّـٰرَتُهُۥٓ إِطۡعَامُ عَشَرَةِ مَسَٰكِينَ مِنۡ أَوۡسَطِ مَا تُطۡعِمُونَ أَهۡلِيكُمۡ أَوۡ كِسۡوَتُهُمۡ أَوۡ تَحۡرِيرُ رَقَبَةٖۖ فَمَن لَّمۡ يَجِدۡ فَصِيَامُ ثَلَٰثَةِ أَيَّامٖۚ ذَٰلِكَ كَفَّـٰرَةُ أَيۡمَٰنِكُمۡ إِذَا حَلَفۡتُمۡۚ وَٱحۡفَظُوٓاْ أَيۡمَٰنَكُمۡۚ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمۡ ءَايَٰتِهِۦ لَعَلَّكُمۡ تَشۡكُرُونَ ٨٩","لا يؤاخذكم الله باللغو في أيمانكم ولكن يؤاخذكم بما عقدتم الأيمان فكفارته إطعام عشرة مساكين من أوسط ما تطعمون أهليكم أو كسوتهم أو تحرير رقبة فمن لم يجد فصيام ثلاثة أيام ذلك كفارة أيمانكم إذا حلفتم واحفظوا أيمانكم كذلك يبين الله لكم آياته لعلكم تشكرون","ގަސްދަކާނުލައި، ބުނާ ބަސްތަކަކުން، ﷲ، ތިޔަބައިމީހުންނަށް އުގޫބާތެއް ނުދެއްވާނެތެވެ. (އެބަހީ: އާދައިގައި ވާހަކަދައްކާ އުޅޭއިރު، ހުވާކުރުމުގެ ގަސްދެއްނެތި، ހުވާގެ ގޮތުގައި ބުނެވޭ ބަހެއް ބޭނުންކުރުމަކީ ކުށެއް ނޫނެވެ.) އެހެނެއްކަމަކު، ގަސްދު ކޮށްގެންކުރާ ހުވާތަކާމެދު، އެކަލާނގެ ތިޔަބައިމީހުންނަށް ޖަޒާ ދެއްވާނެތެވެ. ފަހެ، ހުވާގެ ކައްފާރާއަކީ، ތިޔަބައިމީހުންގެ އަނބިދަރިންނަށް ކާންދީ އުޅޭ މެދުމިނުން، ދިހަ މިސްކީނުންނަށް ކާންދިނުމެވެ. ނުވަތަ އެއުރެންނަށް އަންނައުނު ދިނުމެވެ. ނުވަތަ އަޅަކު މިނިވަންކުރުމެވެ. ފަހެ، (އެއިންކަމެއް ކުރަން) ނުލިބުނުމީހާ، ތިންދުވަހު ރޯދަޔަށް ހުރުމެވެ. އެއީ ތިޔަބައިމީހުން ހުވާކޮށްފި ހިނދެއްގައި (އެބަހީ: ހުވާކޮށް، އެ ހުވަޔާ ޚިލާފު ވެއްޖެ ހިނދެއްގައި) ތިޔަބައިމީހުންގެ ހުވާގެ ކައްފާރާއެވެ. އަދި ތިޔަބައިމީހުންގެ ހުވާތަކަށް ރައްކާތެރިވާށެވެ! ތިޔަބައިމީހުން ޝުކުރުކުރުމަށްޓަކައި، ﷲ، އެކަލާނގެ އާޔަތްތައް ތިޔަބައިމީހުންނަށް އެފަދައިން ބަޔާން ކޮށްދެއްވަތެވެ.","",""],["₅ سورة المائدة","90","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ إِنَّمَا ٱلۡخَمۡرُ وَٱلۡمَيۡسِرُ وَٱلۡأَنصَابُ وَٱلۡأَزۡلَٰمُ رِجۡسٞ مِّنۡ عَمَلِ ٱلشَّيۡطَٰنِ فَٱجۡتَنِبُوهُ لَعَلَّكُمۡ تُفۡلِحُونَ ٩٠","يا أيها الذين آمنوا إنما الخمر والميسر والأنصاب والأزلام رجس من عمل الشيطان فاجتنبوه لعلكم تفلحون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ހަމަކަށަވަރުން، ރާއާއި، ޖުވާކުޅުމާއި، އަޅުކަންކުރަން ހަދާފައި ހުންނަ ބުދުތަކާއި ނަސީބު ހުރިގޮތް ބަލަން ގެންގުޅޭ ދުނިދަނޑިތަކަކީ، ޝައިތާނާގެ ޢަމަލުތަކުގެ ތެރެއިންވާ މުޑުދާރު ތަކެއްޗެވެ. ފަހެ، ތިޔަބައިމީހުން އެކަންތަކާ ދުރުވެގަންނާށެވެ! (އެއީ) ތިޔަބައިމީހުން ދިންނަވައި ނަސީބު ލިބުމަށްޓަކައެވެ.","",""],["₅ سورة المائدة","91","إِنَّمَا يُرِيدُ ٱلشَّيۡطَٰنُ أَن يُوقِعَ بَيۡنَكُمُ ٱلۡعَدَٰوَةَ وَٱلۡبَغۡضَآءَ فِي ٱلۡخَمۡرِ وَٱلۡمَيۡسِرِ وَيَصُدَّكُمۡ عَن ذِكۡرِ ٱللَّهِ وَعَنِ ٱلصَّلَوٰةِۖ فَهَلۡ أَنتُم مُّنتَهُونَ ٩١","إنما يريد الشيطان أن يوقع بينكم العداوة والبغضاء في الخمر والميسر ويصدكم عن ذكر الله وعن الصلاة فهل أنتم منتهون","ޝައިތާނާ އެދޭކަން ކަށަވަރީ، ރާއާއި، ޖުވާގެ ސަބަބުން، ތިޔަބައިމީހުންގެ މެދުގައި އަދާވަތް ތެރިކަމާއި، ރުޅިވެރިކަން އުފެއްދުމަށެވެ. އަދި ﷲ ހަނދުމަކުރުމާއި، ނަމާދުކުރުމަށް ތިޔަބައިމީހުންނަށް ހުރަސްއެޅުމަށެވެ. ފަހެ، ތިޔަބައިމީހުން ތިޔަތިބީ އެކަންތައްތައް ހުއްޓާލަންހެއްޔެވެ؟ (އެބަހީ: ހުއްޓާލާށެވެ!)","",""],["₅ سورة المائدة","92","وَأَطِيعُواْ ٱللَّهَ وَأَطِيعُواْ ٱلرَّسُولَ وَٱحۡذَرُواْۚ فَإِن تَوَلَّيۡتُمۡ فَٱعۡلَمُوٓاْ أَنَّمَا عَلَىٰ رَسُولِنَا ٱلۡبَلَٰغُ ٱلۡمُبِينُ ٩٢","وأطيعوا الله وأطيعوا الرسول واحذروا فإن توليتم فاعلموا أنما على رسولنا البلاغ المبين","އަދި ތިޔަބައިމީހުން ﷲއަށް ކިޔަމަންވާށެވެ! އަދި ތިޔަބައިމީހުން ރަސޫލާއަށް ކިޔަމަންވާށެވެ! އަދި ތިޔަބައިމީހުން ރައްކާތެރިވާށެވެ! ފަހެ، ތިޔަބައިމީހުން ފުރަގަސްދިން ނަމަވެސް، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ރަސޫލާއަށް އޮތީ، ބަޔާން ވެގެންވާ އިއްވެވުންކަން ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₅ سورة المائدة","93","لَيۡسَ عَلَى ٱلَّذِينَ ءَامَنُواْ وَعَمِلُواْ ٱلصَّـٰلِحَٰتِ جُنَاحٞ فِيمَا طَعِمُوٓاْ إِذَا مَا ٱتَّقَواْ وَّءَامَنُواْ وَعَمِلُواْ ٱلصَّـٰلِحَٰتِ ثُمَّ ٱتَّقَواْ وَّءَامَنُواْ ثُمَّ ٱتَّقَواْ وَّأَحۡسَنُواْۚ وَٱللَّهُ يُحِبُّ ٱلۡمُحۡسِنِينَ ٩٣","ليس على الذين آمنوا وعملوا الصالحات جناح فيما طعموا إذا ما اتقوا وآمنوا وعملوا الصالحات ثم اتقوا وآمنوا ثم اتقوا وأحسنوا والله يحب المحسنين","އީމާންވެ، ސާލިހު ޢަމަލު ކޮށްއުޅުނު މީހުން ކައި (ބޮއި) އުޅުނު އެއްޗަކާމެދު، އެއުރެންގެ މައްޗަކަށް ކުށެއް ނެތެވެ. (އެބަހީ: ރާއާއި އަދި އެނޫން ތަކެތި ހަރާމްކުރެއްވުމުގެކުރިން އެތަކެތި ބޭނުންކުރި މީހުންގެ މައްޗަކަށް ކުށެއް ނެތެވެ. އެއީ) އެއުރެން ތަގުވާވެރިވެ، އީމާންވެ، ސާލިހު ޢަމަލުކުޅަނަމައެވެ. ދެންވެސް ތަގުވާވެރިވެ، އީމާން ވީނަމައެވެ. ދެންވެސް ތަގުވާވެރިވެ، ޢަމަލުތައް ރަނގަޅު ކުޅަނަމައެވެ. އިހްސާން ތެރިންދެކެ ﷲ ލޯބިވެވޮޑިގެންވެތެވެ.","",""],["₅ سورة المائدة","94","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَيَبۡلُوَنَّكُمُ ٱللَّهُ بِشَيۡءٖ مِّنَ ٱلصَّيۡدِ تَنَالُهُۥٓ أَيۡدِيكُمۡ وَرِمَاحُكُمۡ لِيَعۡلَمَ ٱللَّهُ مَن يَخَافُهُۥ بِٱلۡغَيۡبِۚ فَمَنِ ٱعۡتَدَىٰ بَعۡدَ ذَٰلِكَ فَلَهُۥ عَذَابٌ أَلِيمٞ ٩٤","يا أيها الذين آمنوا ليبلونكم الله بشيء من الصيد تناله أيديكم ورماحكم ليعلم الله من يخافه بالغيب فمن اعتدى بعد ذلك فله عذاب أليم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ އަތްތަކާއި، ލޮންސިތަކުން އަތުލާ ބައެއް ޝިކާރައިން، ﷲ، ތިޔަބައިމީހުން އިމްތިހާނުކުރައްވާނެތެވެ. (އެއީ) ނުފެންނަ ތާނގައިވެސް، އެކަލާނގެއަށް ބިރުވެތިވާ ބަޔަކު، ﷲ ދެނެވޮޑިގެންވެ، އެކަން ފާޅުކުރެއްވުމަށްޓަކައެވެ. ފަހެ، އެއަށްފަހު (އެކަލާނގެ އަމުރުފުޅު) ފަހަނަޅައި ހިނގައްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["₅ سورة المائدة","95","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تَقۡتُلُواْ ٱلصَّيۡدَ وَأَنتُمۡ حُرُمٞۚ وَمَن قَتَلَهُۥ مِنكُم مُّتَعَمِّدٗا فَجَزَآءٞ مِّثۡلُ مَا قَتَلَ مِنَ ٱلنَّعَمِ يَحۡكُمُ بِهِۦ ذَوَا عَدۡلٖ مِّنكُمۡ هَدۡيَۢا بَٰلِغَ ٱلۡكَعۡبَةِ أَوۡ كَفَّـٰرَةٞ طَعَامُ مَسَٰكِينَ أَوۡ عَدۡلُ ذَٰلِكَ صِيَامٗا لِّيَذُوقَ وَبَالَ أَمۡرِهِۦۗ عَفَا ٱللَّهُ عَمَّا سَلَفَۚ وَمَنۡ عَادَ فَيَنتَقِمُ ٱللَّهُ مِنۡهُۚ وَٱللَّهُ عَزِيزٞ ذُو ٱنتِقَامٍ ٩٥","يا أيها الذين آمنوا لا تقتلوا الصيد وأنتم حرم ومن قتله منكم متعمدا فجزاء مثل ما قتل من النعم يحكم به ذوا عدل منكم هديا بالغ الكعبة أو كفارة طعام مساكين أو عدل ذلك صياما ليذوق وبال أمره عفا الله عما سلف ومن عاد فينتقم الله منه والله عزيز ذو انتقام","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! (ހައްޖަކަށް، ނުވަތަ އުމްރާއަކަށް) ތިޔަބައިމީހުން އިހްރާމް ބަނދެގެންތިބެ (އެއްގަމު) ޝިކާރަ ގަތުލު ނުކުރާށެވެ! އަދި ތިޔަބައިމީހުންގެ ތެރެއިން ގަސްދުގައި، އެފަދަ ޝިކާރައެއް ގަތުލު ކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހެއްގެ ޖަޒާއަކީ، ގަތުލުކުޅަ އެއްޗަކާ އެއްފަދަ އެއްޗެއް، ނަޢަމް ސޫފީގެ ތެރެއިން ދިނުމެވެ. އެ އެއްފަދަ އެއްޗަކާމެދު ހުކުމްކުރާނީ، ތިޔަބައިމީހުންގެ ތެރެއިން ޢަދުލުވެރި ދެމީހެކެވެ. (މި ދޭންޖެހޭނީ) ކައުބަތުﷲގެފުޅަށް ފޯރާ ހަދްޔެއްގެ ގޮތުގައެވެ. ނުވަތަ ކައްފާރާއެއް ދިނުމެވެ. އެއީ މިސްކީނުންނަށް ކާންދިނުމެވެ. ނުވަތަ އެއާ އެއްވަރަށް ރޯދަހިފުމެވެ. އެއީ އޭނާ ކުޅަކަންތަކުގެ ނަތީޖާގެ ރަހަ ލިބިގަތުމަށްޓަކައެވެ. (މި އާޔަތް ބާވައިލެއްވުމުގެ) ކުރިން އިސްވެދިޔަ ކަންތައް ﷲ އަފޫކުރައްވައިފިއެވެ. އަދި އެކަމަށް އެނބުރި އިއާދަ ވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާގެ ކިބައިން ﷲ ބަދަލުހިއްޕަވާނެތެވެ. ﷲއީ، ބަދަލުހިއްޕެވުމުގެ ވެރި، ޢަޒީޒުވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","96","أُحِلَّ لَكُمۡ صَيۡدُ ٱلۡبَحۡرِ وَطَعَامُهُۥ مَتَٰعٗا لَّكُمۡ وَلِلسَّيَّارَةِۖ وَحُرِّمَ عَلَيۡكُمۡ صَيۡدُ ٱلۡبَرِّ مَا دُمۡتُمۡ حُرُمٗاۗ وَٱتَّقُواْ ٱللَّهَ ٱلَّذِيٓ إِلَيۡهِ تُحۡشَرُونَ ٩٦","أحل لكم صيد البحر وطعامه متاعا لكم وللسيارة وحرم عليكم صيد البر ما دمتم حرما واتقوا الله الذي إليه تحشرون","ކަނޑުގެ ކެޔޮޅުކަން ކުރުމާއި، އެކަމުންލިބޭ ކާތަކެތި ތިޔަބައިމީހުންނަށް ހަލާލުކުރައްވާފައިވެއެވެ. (އެއީ) ތިޔަބައިމީހުންނަށާއި، ދަތުރުވެރިންނަށް ބޭނުންކުރެވޭ އެއްޗެއްގެ ގޮތުގައެވެ. އަދި ތިޔަބައިމީހުން، އިހްރާމް ބަނދެގެން ތިބިހާހިނދަކު، އެއްގަމު ޝިކާރަ ތިޔަބައިމީހުންގެ މައްޗަށް ހަރާމްކުރައްވާފައި ވެއެވެ. ތިޔަބައިމީހުން، ﷲއަށް ތަގުވާވެރިވާށެވެ! އެކަލާނގެއީ، އެކަލާނގެ ހަޒުރަތަށް ތިޔަބައިމީހުން މަހުޝަރުކުރައްވާނޭ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","97","۞جَعَلَ ٱللَّهُ ٱلۡكَعۡبَةَ ٱلۡبَيۡتَ ٱلۡحَرَامَ قِيَٰمٗا لِّلنَّاسِ وَٱلشَّهۡرَ ٱلۡحَرَامَ وَٱلۡهَدۡيَ وَٱلۡقَلَـٰٓئِدَۚ ذَٰلِكَ لِتَعۡلَمُوٓاْ أَنَّ ٱللَّهَ يَعۡلَمُ مَا فِي ٱلسَّمَٰوَٰتِ وَمَا فِي ٱلۡأَرۡضِ وَأَنَّ ٱللَّهَ بِكُلِّ شَيۡءٍ عَلِيمٌ ٩٧","جعل الله الكعبة البيت الحرام قياما للناس والشهر الحرام والهدي والقلائد ذلك لتعلموا أن الله يعلم ما في السماوات وما في الأرض وأن الله بكل شيء عليم","ހުރުމަތް ތެރިވެގެންވާ ކައުބަތުﷲގެފުޅާއި، ހުރުމަތް ތެރި މައްސަރުތަކާއި، ހަރަމް ފުޅަށް ހަދިޔާކުރުމުގެ ގޮތުން ކަތިލާ ތަކެއްޗާއި، ހަރަމް ފުޅަށްޓަކައި ފާހަގަކޮށް ގިލަފަތި އަޅުވާފައިވާ ތަކެތި، ﷲ ލައްވާފައިވަނީ މީސްތަކުންގެ ދިރިއުޅުން އަމާންކޮށް ގާއިމުކުރާ ތަކެތި ކަމުގައެވެ. އެއީ ހަމަކަށަވަރުން، އުޑުތަކުގައިވާހާ ކަމަކާއި، ބިމުގައި ވާހާކަމެއް ﷲ ދެނެވޮޑިގެންވާކަމާއި، ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެކަން ތިޔަބައިމީހުން ދެނެގަތުމަށްޓަކައެވެ.","",""],["₅ سورة المائدة","98","ٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ شَدِيدُ ٱلۡعِقَابِ وَأَنَّ ٱللَّهَ غَفُورٞ رَّحِيمٞ ٩٨","اعلموا أن الله شديد العقاب وأن الله غفور رحيم","ހަމަކަށަވަރުން، ﷲއީ، އުގޫބާތް ގަދަފަދަ ވެގެންވާ ރަސްކަލާނގެ ކަމާއި، ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން، ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₅ سورة المائدة","99","مَّا عَلَى ٱلرَّسُولِ إِلَّا ٱلۡبَلَٰغُۗ وَٱللَّهُ يَعۡلَمُ مَا تُبۡدُونَ وَمَا تَكۡتُمُونَ ٩٩","ما على الرسول إلا البلاغ والله يعلم ما تبدون وما تكتمون","(ރިސާލަތް) އިއްވެވުން މެނުވީ، ރަސޫލާގެ މައްޗަކަށް ނުވެއެވެ. އަދި ތިޔަބައިމީހުން ފާޅުކުރާ ކަންތަކާއި، ވަންހަނާކުރާ ކަންތައް، ﷲ ދެނެވޮޑިގެންވެތެވެ.","",""],["₅ سورة المائدة","100","قُل لَّا يَسۡتَوِي ٱلۡخَبِيثُ وَٱلطَّيِّبُ وَلَوۡ أَعۡجَبَكَ كَثۡرَةُ ٱلۡخَبِيثِۚ فَٱتَّقُواْ ٱللَّهَ يَـٰٓأُوْلِي ٱلۡأَلۡبَٰبِ لَعَلَّكُمۡ تُفۡلِحُونَ ١٠٠","قل لا يستوي الخبيث والطيب ولو أعجبك كثرة الخبيث فاتقوا الله يا أولي الألباب لعلكم تفلحون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ނުބައިކަންތަކުގެ ގިނަކަން، ތިބާ އަޖާއިބު ކޮށްލިޔަސް، ނުބައިކަންތަކާއި، ރަނގަޅު ކަންތައް ހަމަހަމަވެގެނެއް ނުވެއެވެ. އޭ ބުއްދީގެ އަހުލުވެރިންނޭވެ! ފަހެ، ތިޔަބައިމީހުން، ﷲއަށް ތަގުވާވެރިވާށެވެ! (އެއީ) ތިޔަބައިމީހުން ދިންނަވައި ނަސީބު ލިބުމަށްޓަކައެވެ.","",""],["₅ سورة المائدة","101","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تَسۡـَٔلُواْ عَنۡ أَشۡيَآءَ إِن تُبۡدَ لَكُمۡ تَسُؤۡكُمۡ وَإِن تَسۡـَٔلُواْ عَنۡهَا حِينَ يُنَزَّلُ ٱلۡقُرۡءَانُ تُبۡدَ لَكُمۡ عَفَا ٱللَّهُ عَنۡهَاۗ وَٱللَّهُ غَفُورٌ حَلِيمٞ ١٠١","يا أيها الذين آمنوا لا تسألوا عن أشياء إن تبد لكم تسؤكم وإن تسألوا عنها حين ينزل القرآن تبد لكم عفا الله عنها والله غفور حليم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންނަށް އެކަންކަން ފާޅުކުރައްވައިފިނަމަ، ތިޔަބައިމީހުންނަށް އުނދަގޫވެ، ނުރުހުންވާނޭ ކަންކަމާމެދު ތިޔަބައިމީހުން ސުވާލު ނުކުރާށެވެ. އަދި ގުރްއާން ބާވައިލައްވާހިނދު އެކަންކަމާމެދު ތިޔަބައިމީހުން ސުވާލުކުރާނަމަ، އެކަންކަން ތިޔަބައިމީހުންނަށް ފާޅުކުރައްވައިފާނެތެވެ. (އިސްވެގޮސްފައިވާ) ސުވާލުކުރުމުގެ ކުށް، ﷲ އަފޫކުރައްވައިފިއެވެ. ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ހަލީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","102","قَدۡ سَأَلَهَا قَوۡمٞ مِّن قَبۡلِكُمۡ ثُمَّ أَصۡبَحُواْ بِهَا كَٰفِرِينَ ١٠٢","قد سألها قوم من قبلكم ثم أصبحوا بها كافرين","ތިޔަބައިމީހުންގެ ކުރިން އުޅުނު ބަޔަކުވެސް، ހަމަކަށަވަރުން، އެފަދަ ސުވާލުކުރިއެވެ. ދެން (އެކަންކަމުގެ ހުކުމް ބަޔާންކުރެއްވި ހިނދު) އެކަންކަމަށް ކާފިރުވި ބަޔަކު ކަމުގައި އެއުރެންވިއެވެ.","",""],["₅ سورة المائدة","103","مَا جَعَلَ ٱللَّهُ مِنۢ بَحِيرَةٖ وَلَا سَآئِبَةٖ وَلَا وَصِيلَةٖ وَلَا حَامٖ وَلَٰكِنَّ ٱلَّذِينَ كَفَرُواْ يَفۡتَرُونَ عَلَى ٱللَّهِ ٱلۡكَذِبَۖ وَأَكۡثَرُهُمۡ لَا يَعۡقِلُونَ ١٠٣","ما جعل الله من بحيرة ولا سائبة ولا وصيلة ولا حام ولكن الذين كفروا يفترون على الله الكذب وأكثرهم لا يعقلون","ބަޙީރާއާއި، ސާއިބާއާއި، ވަސީލަތާއި، ޙާމީއާއި، މިތަކެތި ހުރުމަތް ތެރި ތަކެތި ކަމުގައި ﷲ ލައްވައިފައެއް ނުވެއެވެ. އެހެނެއްކަމަކު، ކާފިރުވި މީހުން ﷲއާމެދު ދޮގުތައް ހަދައި އުޅެތެވެ. އަދި އޭގެތެރެއިން ގިނަމީހުންނަކަށް ނުވިސްނެއެވެ. (ނޯޓު: ބަޙީރާއާއި، ސާއިބާއާއި، ވަސީލަތާއި، ޙާމީއާއި، މި ތަކެއްޗަކީ ޖާހިލީ ޒަމާނުގައި، އަރަބީން އަޅުކަންކޮށްއުޅުނު ބުދުތަކަށްޓަކައި، ނަޢަމް ސޫފީގެ ތެރެއިން، މިނަންތަކުން ހާއްސަ ކޮށްފައިވާ ތަކެއްޗެވެ.)","",""],["₅ سورة المائدة","104","وَإِذَا قِيلَ لَهُمۡ تَعَالَوۡاْ إِلَىٰ مَآ أَنزَلَ ٱللَّهُ وَإِلَى ٱلرَّسُولِ قَالُواْ حَسۡبُنَا مَا وَجَدۡنَا عَلَيۡهِ ءَابَآءَنَآۚ أَوَلَوۡ كَانَ ءَابَآؤُهُمۡ لَا يَعۡلَمُونَ شَيۡـٔٗا وَلَا يَهۡتَدُونَ ١٠٤","وإذا قيل لهم تعالوا إلى ما أنزل الله وإلى الرسول قالوا حسبنا ما وجدنا عليه آباءنا أولو كان آباؤهم لا يعلمون شيئا ولا يهتدون","އަދި ﷲ ބާވާލައްވާފައިވާ ފޮތަށާއި، ރަސޫލާ އަންގަވާގޮތަށް ތަބާ ވާން ތިޔަބައިމީހުން އަންނާށޭ އެއުރެން ބުނެފިނަމަ، އެއުރެން ބުނެތެވެ. ތިމަންމެންގެ ކާބަފައިން އުޅުނީތީ ތިމަންމެންނަށް ފެނުނުގޮތް ތިމަންމެންނަށް ފުދެއެވެ. ފަހެ، އެއުރެންގެ ކާބަފައިންނީ، އެއްވެސް އެއްޗެއް ނުދަންނަ، އަދި ތެދުމަގު ލިބިގެންނުވާ ބަޔަކުކަމުގައި ވީނަމަވެސް ހެއްޔެވެ؟","",""],["₅ سورة المائدة","105","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ عَلَيۡكُمۡ أَنفُسَكُمۡۖ لَا يَضُرُّكُم مَّن ضَلَّ إِذَا ٱهۡتَدَيۡتُمۡۚ إِلَى ٱللَّهِ مَرۡجِعُكُمۡ جَمِيعٗا فَيُنَبِّئُكُم بِمَا كُنتُمۡ تَعۡمَلُونَ ١٠٥","يا أيها الذين آمنوا عليكم أنفسكم لا يضركم من ضل إذا اهتديتم إلى الله مرجعكم جميعا فينبئكم بما كنتم تعملون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތައް ރައްކާތެރިކޮށް، އިސްލާހުކުރާށެވެ! ތިޔަބައިމީހުންނަށް ތެދުމަގު ލިބިއްޖެނަމަ، މަގުފުރެދުނު މީހުންގެ ކިބައިން، ތިޔަބައިމީހުންނަށް ގެއްލުމެއް ނުލިބޭހުށްޓެވެ. ތިޔަބައިމީހުން އެންމެން އެނބުރިދިއުންއޮތީ، ﷲގެ ހަޒުރަތަށެވެ. ފަހެ، އޭރުން ތިޔަބައިމީހުން ކޮށްއުޅުނު ކަންތަކުގެ ޚަބަރު، ތިޔަބައިމީހުންނަށް އެކަލާނގެ އަންގަވާނެތެވެ.","",""],["₅ سورة المائدة","106","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ شَهَٰدَةُ بَيۡنِكُمۡ إِذَا حَضَرَ أَحَدَكُمُ ٱلۡمَوۡتُ حِينَ ٱلۡوَصِيَّةِ ٱثۡنَانِ ذَوَا عَدۡلٖ مِّنكُمۡ أَوۡ ءَاخَرَانِ مِنۡ غَيۡرِكُمۡ إِنۡ أَنتُمۡ ضَرَبۡتُمۡ فِي ٱلۡأَرۡضِ فَأَصَٰبَتۡكُم مُّصِيبَةُ ٱلۡمَوۡتِۚ تَحۡبِسُونَهُمَا مِنۢ بَعۡدِ ٱلصَّلَوٰةِ فَيُقۡسِمَانِ بِٱللَّهِ إِنِ ٱرۡتَبۡتُمۡ لَا نَشۡتَرِي بِهِۦ ثَمَنٗا وَلَوۡ كَانَ ذَا قُرۡبَىٰ وَلَا نَكۡتُمُ شَهَٰدَةَ ٱللَّهِ إِنَّآ إِذٗا لَّمِنَ ٱلۡأٓثِمِينَ ١٠٦","يا أيها الذين آمنوا شهادة بينكم إذا حضر أحدكم الموت حين الوصية اثنان ذوا عدل منكم أو آخران من غيركم إن أنتم ضربتم في الأرض فأصابتكم مصيبة الموت تحبسونهما من بعد الصلاة فيقسمان بالله إن ارتبتم لا نشتري به ثمنا ولو كان ذا قربى ولا نكتم شهادة الله إنا إذا لمن الآثمين","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންކުރެ މީހެއްގެ ގާތަށް، މަރު ޙާޒިރުު ވެއްޖެނަމަ، ވަސިއްޔަތްކުރާހިނދުގައި، ތިޔަބައިމީހުންގެ މެދުގައި، ތިޔަބައިމީހުންގެ ތެރެއިން ޢަދުލުވެރި ދެފިރިހެނުން ހެކިކުރުން ހުށްޓެވެ. ނުވަތަ ތިޔަބައިމީހުން ބިމުގައި، ދަތުރުފަތުރުކޮށް އުޅެނިކޮށް، މަރުގެ މުސީބަތް ތިޔަބައިމީހުންނަށް ޖެހިއްޖެނަމަ، ތިޔަބައިމީހުން ނޫންމީހުންގެ ތެރެއިން، ދެމީހުން ހެކިކުރުން ހުށްޓެވެ. (އެދެމީހުންގެ ހެކިބަހާމެދުގައި) ތިޔަބައިމީހުންނަށް ޝައްކު ވެއްޖެނަމަ، ނަމާދުގެ ފަހުން، ތިޔަބައިމީހުން އެދެމީހުން ހިފަހައްޓާނީއެވެ. ދެން އެ ދެ ހެކީން، ﷲ ގަންދީ ހުވާކުރާނީއެވެ. އެ މީހަކީ (އެބަހީ: އެމީހަކަށްޓަކައި ހުވާކުރެވޭ މީހަކީ) ގާތްތިމާގެ މީހަކު ކަމުގައިވިޔަސް، އެހުވަޔަށް އެއްވެސް އަގެއް އަތުލާފައި ނުވާކަމަށާއި، ﷲގެ ހެކިބަސް، ތިމަންމެން ވަންހަނާ ނުކުރާކަމަށެވެ. އެކަން ކޮށްފިނަމަ، އޭރުން ހަމަކަށަވަރުން، ތިމަންމެންވާހުށީ ފާފަވެރިންގެ ތެރެއިންނެވެ.","",""],["₅ سورة المائدة","107","فَإِنۡ عُثِرَ عَلَىٰٓ أَنَّهُمَا ٱسۡتَحَقَّآ إِثۡمٗا فَـَٔاخَرَانِ يَقُومَانِ مَقَامَهُمَا مِنَ ٱلَّذِينَ ٱسۡتَحَقَّ عَلَيۡهِمُ ٱلۡأَوۡلَيَٰنِ فَيُقۡسِمَانِ بِٱللَّهِ لَشَهَٰدَتُنَآ أَحَقُّ مِن شَهَٰدَتِهِمَا وَمَا ٱعۡتَدَيۡنَآ إِنَّآ إِذٗا لَّمِنَ ٱلظَّـٰلِمِينَ ١٠٧","فإن عثر على أنهما استحقا إثما فآخران يقومان مقامهما من الذين استحق عليهم الأوليان فيقسمان بالله لشهادتنا أحق من شهادتهما وما اعتدينا إنا إذا لمن الظالمين","ދެން އެ ދެމީހުން ފާފަވެރި ވެއްޖެކަމަށް ފެނިއްޖެނަމަ، އެދެމީހުންގެ މަގާމްގައި، އެހެން ދެމީހުން ގާއިމު ވާނީއެވެ. (އެއީ) އެބަޔަކަށް ވަސިއްޔަތް ހައްގު ވެގެންވީ މީހުންގެ ތެރެއިން، މަރުވި މީހާއާ އެންމެގާތް ދެމީހެކެވެ. ދެން އެ ދެމީހުން، ﷲ ގަންދީ ހުވާކުރާނީއެވެ. ހަމަކަށަވަރުން، ތިމަންމެންގެ ހެކިބަސް އެދެމީހުންގެ ހެކިބަހަށްވުރެ ތެދުކަން ބޮޑުކަމަށާއި، ތިމަންމެން ހައްދުފަހަނަޅައި ނުދާކަމަށެވެ. އެހެން އެކަންކޮށްފިނަމަ، ހަމަކަށަވަރުން، ތިމަންމެން ވާހުށީ، އަނިޔާވެރިންގެ ތެރެއިންނެވެ.","",""],["₅ سورة المائدة","108","ذَٰلِكَ أَدۡنَىٰٓ أَن يَأۡتُواْ بِٱلشَّهَٰدَةِ عَلَىٰ وَجۡهِهَآ أَوۡ يَخَافُوٓاْ أَن تُرَدَّ أَيۡمَٰنُۢ بَعۡدَ أَيۡمَٰنِهِمۡۗ وَٱتَّقُواْ ٱللَّهَ وَٱسۡمَعُواْۗ وَٱللَّهُ لَا يَهۡدِي ٱلۡقَوۡمَ ٱلۡفَٰسِقِينَ ١٠٨","ذلك أدنى أن يأتوا بالشهادة على وجهها أو يخافوا أن ترد أيمان بعد أيمانهم واتقوا الله واسمعوا والله لا يهدي القوم الفاسقين","އެއުރެން ހެކިބަސް އަދާކުރާން އޮތްގޮތުގައި، އަދާކުރުމަށް ގާތްކަންބޮޑީ އެގޮތެވެ. ނުވަތަ އެއުރެންގެ ހުވަޔަށްފަހު، ހުވާ ރައްދުވެގެން އަތުވެދާނެކަމަށް، އެއުރެން ބިރުވެތިވުން ގާތްކަންބޮޑީވެސް އެގޮތެވެ. ފަހެ، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވެ، އަޑުއަހާށެވެ! ފާސިގު ވީ މީހުންނަށް، ﷲ ތެދުމަގެއް ނުދައްކަވާނެތެވެ.","",""],["₅ سورة المائدة","109","۞يَوۡمَ يَجۡمَعُ ٱللَّهُ ٱلرُّسُلَ فَيَقُولُ مَاذَآ أُجِبۡتُمۡۖ قَالُواْ لَا عِلۡمَ لَنَآۖ إِنَّكَ أَنتَ عَلَّـٰمُ ٱلۡغُيُوبِ ١٠٩","يوم يجمع الله الرسل فيقول ماذا أجبتم قالوا لا علم لنا إنك أنت علام الغيوب","ﷲ، ރަސޫލުން އެއްކުރައްވާ ދުވަސް ހަނދުމަކުރާށެވެ! ފަހެ، އެކަލާނގެ އެބޭކަލުންނަށް ވަހީކުރައްވާނެތެވެ. (މީސްތަކުންގެ ފަރާތުން) ތިޔަބޭކަލުންނަށް ލިބުނީ ކޮން އިޖާބައެއް ހެއްޔެވެ؟ އެބޭކަލުން ދަންނަވާނެތެވެ. އަޅަމެންނަށް އެކަމުގެ އެނގުމެއް ނުވެއެވެ. ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ، ޣައިބުތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","110","إِذۡ قَالَ ٱللَّهُ يَٰعِيسَى ٱبۡنَ مَرۡيَمَ ٱذۡكُرۡ نِعۡمَتِي عَلَيۡكَ وَعَلَىٰ وَٰلِدَتِكَ إِذۡ أَيَّدتُّكَ بِرُوحِ ٱلۡقُدُسِ تُكَلِّمُ ٱلنَّاسَ فِي ٱلۡمَهۡدِ وَكَهۡلٗاۖ وَإِذۡ عَلَّمۡتُكَ ٱلۡكِتَٰبَ وَٱلۡحِكۡمَةَ وَٱلتَّوۡرَىٰةَ وَٱلۡإِنجِيلَۖ وَإِذۡ تَخۡلُقُ مِنَ ٱلطِّينِ كَهَيۡـَٔةِ ٱلطَّيۡرِ بِإِذۡنِي فَتَنفُخُ فِيهَا فَتَكُونُ طَيۡرَۢا بِإِذۡنِيۖ وَتُبۡرِئُ ٱلۡأَكۡمَهَ وَٱلۡأَبۡرَصَ بِإِذۡنِيۖ وَإِذۡ تُخۡرِجُ ٱلۡمَوۡتَىٰ بِإِذۡنِيۖ وَإِذۡ كَفَفۡتُ بَنِيٓ إِسۡرَـٰٓءِيلَ عَنكَ إِذۡ جِئۡتَهُم بِٱلۡبَيِّنَٰتِ فَقَالَ ٱلَّذِينَ كَفَرُواْ مِنۡهُمۡ إِنۡ هَٰذَآ إِلَّا سِحۡرٞ مُّبِينٞ ١١٠","إذ قال الله يا عيسى ابن مريم اذكر نعمتي عليك وعلى والدتك إذ أيدتك بروح القدس تكلم الناس في المهد وكهلا وإذ علمتك الكتاب والحكمة والتوراة والإنجيل وإذ تخلق من الطين كهيئة الطير بإذني فتنفخ فيها فتكون طيرا بإذني وتبرئ الأكمه والأبرص بإذني وإذ تخرج الموتى بإذني وإذ كففت بني إسرائيل عنك إذ جئتهم بالبينات فقال الذين كفروا منهم إن هذا إلا سحر مبين","ﷲ، ވަހީކުރެއްވިހިނދު، ހަނދުމަކުރާށެވެ! އޭ މަރިޔަމްގެފާނުގެ ދަރިކަލުން ޢީސާގެފާނޭވެ! ކަލޭގެފާނަށާއި، ކަލޭގެފާނުންގެ މައިކަނބަލުންނަށް ތިމަންރަސްކަލާނގެ ދެއްވި ނިއުމަތް ހަނދުމަކުރައްވާށެވެ! (އެއީ) ޖިބްރީލުގެފާނު ފޮނުއްވައި ކަލޭގެފާނަށް، ތިމަންރަސްކަލާނގެ ބާރުދެއްވިހިނދެވެ. ޅަފަތުގެ ދާނުގައްޔާއި، ދެވަންފުރާގައި، ކަލޭގެފާނު މީސްތަކުންނާ ވާހަކަ ދައްކަވަމުއެވެ. އަދި ފޮތާއި، ހިކުމަތާއި، ތައުރާތާއި، އިންޖީލު، ކަލޭގެފާނަށް އުނގަންނައިދެއްވި ހިނދެވެ. އަދި ތިމަންރަސްކަލާނގެ އިޒުނަ ފުޅާއެކު، ކަލޭގެފާނު މަށީން ދޫންޏެއްގެ ސިފަހައްދަވައި، އެއަށް ފުމެލެއްވުމުން، ތިމަންރަސްކަލާނގެ އިޒުނަ ފުޅާއެކު، ދޫންޏަކަށްވެގެން ދިޔަހިނދެވެ. ލޯފަންވެފައިވާ މީހުންނާއި، ބަރަޞް ބަލިޖެހިފައިވާ މީހުންނަށް ކަލޭގެފާނު، ތިމަންރަސްކަލާނގެ އިޒުނަ ފުޅާއެކު ފަސޭހަކޮށްދެއްވި ހިނދެވެ. އަދި ތިމަންރަސްކަލާނގެ އިޒުނަ ފުޅާއެކު، ކަލޭގެފާނު، މަރުވެފައިތިބި މީހުން ދިރުއްވައި، ނެރުއްވިހިނދެވެ. ކަނޑައެޅި ބަޔާން ވެގެންހުރި ހެކިތަކާއިގެން، ކަލޭގެފާނު އިސްރާއީލުގެދަރިންގެ ގާތަށް ވަޑައިގަތްހިނދު، އެއުރެންގެ އުނދަގޫތައް، ކަލޭގެފާނުގެ ކިބައިން ދުރުކުރެއްވިހިނދެވެ. ފަހެ، އެއުރެންގެ ތެރެއިން ކާފިރުވި މީހުން ބުނޫއެވެ. މިކަންތައްތަކަކީ، ފާޅުވެ ބަޔާން ވެގެން ހުރި ޖާދޫކަމުގައި ނޫނީ ނުވެއެވެ.","",""],["₅ سورة المائدة","111","وَإِذۡ أَوۡحَيۡتُ إِلَى ٱلۡحَوَارِيِّـۧنَ أَنۡ ءَامِنُواْ بِي وَبِرَسُولِي قَالُوٓاْ ءَامَنَّا وَٱشۡهَدۡ بِأَنَّنَا مُسۡلِمُونَ ١١١","وإذ أوحيت إلى الحواريين أن آمنوا بي وبرسولي قالوا آمنا واشهد بأننا مسلمون","އަދި ތިމަންރަސްކަލާނގެއަށާއި، ތިމަންރަސްކަލާނގެ ރަސޫލާއަށް އީމާން ވުމަށް ޙަވާރިއްޔަންނަށް، ތިމަންރަސްކަލާނގެ އެންގެވިހިނދު ހަނދުމަކުރާށެވެ! ދެން ޙަވާރިއްޔަން ދެންނެވޫއެވެ. ތިމަންމެން އީމާން ވެއްޖައީމުއެވެ. އަދި ތިމަންމެންނީ ބޯލަނބައި، ކިޔަމަންވެގެންތިބި ބަޔަކުކަމަށް އިބަރަސްކަލާނގެ ހެކިވެވޮޑިގެންފާނދޭވެ! (ނޯޓު: ޙަވާރިއްޔަންނަކީ، ޢީސާގެފާނަށް ތަބާ ވެގެން އެކަލޭގެފާނުގެ އަރިހުގައި އުޅުއްވި އެންމެ އިހްލާސް ތެރި އެކުވެރިންނެވެ.)","",""],["₅ سورة المائدة","112","إِذۡ قَالَ ٱلۡحَوَارِيُّونَ يَٰعِيسَى ٱبۡنَ مَرۡيَمَ هَلۡ يَسۡتَطِيعُ رَبُّكَ أَن يُنَزِّلَ عَلَيۡنَا مَآئِدَةٗ مِّنَ ٱلسَّمَآءِۖ قَالَ ٱتَّقُواْ ٱللَّهَ إِن كُنتُم مُّؤۡمِنِينَ ١١٢","إذ قال الحواريون يا عيسى ابن مريم هل يستطيع ربك أن ينزل علينا مائدة من السماء قال اتقوا الله إن كنتم مؤمنين","ޙަވާރިއްޔަން ދެންނެވިހިނދު ހަނދުމަކުރާށެވެ! އޭ މަރިޔަމްގެފާނުގެ ދަރިކަލުން ޢީސާގެފާނޭވެ! ތިމަންމެންނަށް ކާތަކެތީގެ ދޮލަނގެއް، އުޑުން ބާވައިލެއްވުމަށް ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ކުޅަދުންވަންތަވެގެން ވޭތޯއެވެ؟ އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން އީމާން ވެގެންތިބި ބަޔަކު ކަމުގައި ވަނީނަމަ، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ!","",""],["₅ سورة المائدة","113","قَالُواْ نُرِيدُ أَن نَّأۡكُلَ مِنۡهَا وَتَطۡمَئِنَّ قُلُوبُنَا وَنَعۡلَمَ أَن قَدۡ صَدَقۡتَنَا وَنَكُونَ عَلَيۡهَا مِنَ ٱلشَّـٰهِدِينَ ١١٣","قالوا نريد أن نأكل منها وتطمئن قلوبنا ونعلم أن قد صدقتنا ونكون عليها من الشاهدين","އެއުރެން ދެންނެވޫއެވެ. ތިމަންމެން އެދެނީ، އެއިން ކެއުމަށާއި، ތިމަންމެންގެ ހިތްތައް ހަމަޖެހުމަށެވެ. އަދި ކަލޭގެފާނު ވިދާޅުވީ ތެދެއްކަން ތިމަންމެންނަށް އެނގުމަށެވެ. އަދި އެކަމުގެ މައްޗަށް ހެކިވާ މީހުންގެ ތެރެއިން ތިމަންމެން ވުމަށެވެ.","",""],["₅ سورة المائدة","114","قَالَ عِيسَى ٱبۡنُ مَرۡيَمَ ٱللَّهُمَّ رَبَّنَآ أَنزِلۡ عَلَيۡنَا مَآئِدَةٗ مِّنَ ٱلسَّمَآءِ تَكُونُ لَنَا عِيدٗا لِّأَوَّلِنَا وَءَاخِرِنَا وَءَايَةٗ مِّنكَۖ وَٱرۡزُقۡنَا وَأَنتَ خَيۡرُ ٱلرَّـٰزِقِينَ ١١٤","قال عيسى ابن مريم اللهم ربنا أنزل علينا مائدة من السماء تكون لنا عيدا لأولنا وآخرنا وآية منك وارزقنا وأنت خير الرازقين","މަރިޔަމްގެފާނުގެ ދަރިކަލުން ޢީސާގެފާނު ވިދާޅުވިއެވެ. އޭ ހައްދަވާ ބޮޑުކުރެއްވި އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! ކާތަކެތީގެ ދޮލަނގެއް އަޅަމެންނަށް އުޑުން ބާވައިލައްވާނދޭވެ! އެއީ އަޅަމެންގެ ކުރީގެ މީހުންނާއި، ފަހުގެ މީހުންނަށް ޢީދެއް ކަމުގައި ވުމަށެވެ. އަދި އިބަރަސްކަލާނގެ ހަޒުރަތުން އައި ހެތްކެއްގެ ގޮތުގައެވެ. އަދި އަޅަމެންނަށް ރިޒްގު ދެއްވައިފާނދޭވެ! އިބަރަސްކަލާނގެއީ، ރިޒްގު ދެއްވާ، އެންމެ ހެޔޮ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","115","قَالَ ٱللَّهُ إِنِّي مُنَزِّلُهَا عَلَيۡكُمۡۖ فَمَن يَكۡفُرۡ بَعۡدُ مِنكُمۡ فَإِنِّيٓ أُعَذِّبُهُۥ عَذَابٗا لَّآ أُعَذِّبُهُۥٓ أَحَدٗا مِّنَ ٱلۡعَٰلَمِينَ ١١٥","قال الله إني منزلها عليكم فمن يكفر بعد منكم فإني أعذبه عذابا لا أعذبه أحدا من العالمين","ﷲ، ވަހީކުރެއްވިއެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް އެ ދޮލަނގު ބާވައިލައްވާހުށީމެވެ. ފަހެ، އެއަށްފަހު ތިޔަބައިމީހުންގެ ތެރެއިން، ކާފިރު ވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އާލަމްތަކުގެ ތެރެއިން އެކަކަށްވެސް، ތިމަންރަސްކަލާނގެ ނުދެއްވާ އަޒާބެއް އެމީހަކަށް ދެއްވާހުށީމެވެ.","",""],["₅ سورة المائدة","116","وَإِذۡ قَالَ ٱللَّهُ يَٰعِيسَى ٱبۡنَ مَرۡيَمَ ءَأَنتَ قُلۡتَ لِلنَّاسِ ٱتَّخِذُونِي وَأُمِّيَ إِلَٰهَيۡنِ مِن دُونِ ٱللَّهِۖ قَالَ سُبۡحَٰنَكَ مَا يَكُونُ لِيٓ أَنۡ أَقُولَ مَا لَيۡسَ لِي بِحَقٍّۚ إِن كُنتُ قُلۡتُهُۥ فَقَدۡ عَلِمۡتَهُۥۚ تَعۡلَمُ مَا فِي نَفۡسِي وَلَآ أَعۡلَمُ مَا فِي نَفۡسِكَۚ إِنَّكَ أَنتَ عَلَّـٰمُ ٱلۡغُيُوبِ ١١٦","وإذ قال الله يا عيسى ابن مريم أأنت قلت للناس اتخذوني وأمي إلهين من دون الله قال سبحانك ما يكون لي أن أقول ما ليس لي بحق إن كنت قلته فقد علمته تعلم ما في نفسي ولا أعلم ما في نفسك إنك أنت علام الغيوب","ﷲ، ވަހީކުރެއްވިހިނދު، ހަނދުމަކުރާށެވެ! އޭ މަރިޔަމްގެފާނުގެ ދަރިކަލުން ޢީސާގެފާނެވެ! ﷲ ފިޔަވައި، ތިމަންނާއާއި، ތިމަންގެ މައިކަނބަލުންނީ، ދެ އިލާހުން ކަމުގައި ތިޔަބައިމީހުން ހިފާށޭ ކަލޭގެފާނު މީސްތަކުންނަށް ވިދާޅުވީމުތޯއެވެ؟ އެކަލޭގެފާނު ދެންނެވިއެވެ. އިބަރަސްކަލާނގެ ހުސް ތާހިރު ވަންތަކަމާއެވެ! ބުނުމުގެ ހައްގު މިއަޅާޔަށް ލިބިގެންނުވާ ބަހެއްބުނުން، މިއަޅާއަކަށް ނުވެއެވެ. މިއަޅާ އެބަސްބުނިނަމަ، އިބަރަސްކަލާނގެ އެކަން ދެނެވޮޑިގެންވާނެކަން ކަށަވަރެވެ. މިއަޅާގެ ހިތުގައިވާ ކަންތައްވެސް، އިބަރަސްކަލާނގެ ދެނެވޮޑިގެންވަމުއެވެ. އިބަރަސްކަލާނގެ އިރާދަފުޅުގައި ވާކަންތައް، މިއަޅާއަކަށް އެނގިގެނެއް ނުވެއެވެ. ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ، ވަންހަނާގައި ވާހައި ކަމެއްވެސް، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","117","مَا قُلۡتُ لَهُمۡ إِلَّا مَآ أَمَرۡتَنِي بِهِۦٓ أَنِ ٱعۡبُدُواْ ٱللَّهَ رَبِّي وَرَبَّكُمۡۚ وَكُنتُ عَلَيۡهِمۡ شَهِيدٗا مَّا دُمۡتُ فِيهِمۡۖ فَلَمَّا تَوَفَّيۡتَنِي كُنتَ أَنتَ ٱلرَّقِيبَ عَلَيۡهِمۡۚ وَأَنتَ عَلَىٰ كُلِّ شَيۡءٖ شَهِيدٌ ١١٧","ما قلت لهم إلا ما أمرتني به أن اعبدوا الله ربي وربكم وكنت عليهم شهيدا ما دمت فيهم فلما توفيتني كنت أنت الرقيب عليهم وأنت على كل شيء شهيد","އިބަރަސްކަލާނގެ، މިއަޅާއަށް އަމުރުކުރައްވާފައިވާ އެއްޗެއް މެނުވީ، މިއަޅާ އެއުރެންނަކަށް ނުބުނަމެވެ. (ބުނީ) ތިމަންގެވެރި، އަދި ތިޔަބައިމީހުންގެވެސް ވެރި، ﷲއަށް ތިޔަބައިމީހުން އަޅުކަންކުރާށޭ އެވެ. އެއުރެންގެ ތެރޭގައި، މިއަޅާ ހުރިހައި ހިނދަކު، އެއުރެންގެ މައްޗަށް ހެކިވެރިޔަކު ކަމުގައި ވީމެވެ. ދެން އިބަރަސްކަލާނގެ، މިއަޅާ ގެންދެވިހިނދު، އެއުރެންގެ މައްޗަށް ބައްލަވާވޮޑިގެންވާ ކަލަކުކަމުގައި، އިބަރަސްކަލާނގެ ވޮޑިގެންވީމުއެވެ. އިބަރަސްކަލާނގެއީ، ކޮންމެކަމެއްގެ މައްޗަށް ހެކިވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","118","إِن تُعَذِّبۡهُمۡ فَإِنَّهُمۡ عِبَادُكَۖ وَإِن تَغۡفِرۡ لَهُمۡ فَإِنَّكَ أَنتَ ٱلۡعَزِيزُ ٱلۡحَكِيمُ ١١٨","إن تعذبهم فإنهم عبادك وإن تغفر لهم فإنك أنت العزيز الحكيم","އެއުރެންނަށް، އިބަރަސްކަލާނގެ އަޒާބު ދެއްވާނަމަ، ފަހެ، ހަމަކަށަވަރުން، އެއުރެންނީ، އިބަރަސްކަލާނގެ އަޅުންނެވެ. އަދި އެއުރެންނަށް އިބަރަސްކަލާނގެ ފާފަފުއްސަވާނަމަ، ފަހެ، ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ، ޢަޒީޒުވަންތަ ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₅ سورة المائدة","119","قَالَ ٱللَّهُ هَٰذَا يَوۡمُ يَنفَعُ ٱلصَّـٰدِقِينَ صِدۡقُهُمۡۚ لَهُمۡ جَنَّـٰتٞ تَجۡرِي مِن تَحۡتِهَا ٱلۡأَنۡهَٰرُ خَٰلِدِينَ فِيهَآ أَبَدٗاۖ رَّضِيَ ٱللَّهُ عَنۡهُمۡ وَرَضُواْ عَنۡهُۚ ذَٰلِكَ ٱلۡفَوۡزُ ٱلۡعَظِيمُ ١١٩","قال الله هذا يوم ينفع الصادقين صدقهم لهم جنات تجري من تحتها الأنهار خالدين فيها أبدا رضي الله عنهم ورضوا عنه ذلك الفوز العظيم","ﷲ، ވަހީކުރައްވާނެތެވެ. މިއީ، ތެދުވެރިންނަށް، އެއުރެންގެ ތެދުވެރިކަން، މަންފާކޮށްދޭނޭ ދުވަހެވެ. އެތާނގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތައް، އެއުރެންނަށް ހުށްޓެވެ. އެ ސުވަރުގެތަކުގައި، އެއުރެން އަބަދަށް ދެމިތިބޭ ގޮތުގައެވެ. ﷲ، އެއުރެންނަށް ރުހިވޮޑިގެންވެއެވެ. އަދި އެއުރެންވެސް، އެކަލާނގެއަށް ރުހިގެންވެއެވެ. ބޮޑުވެގެންވާ ނަސީބު ލިބުމަކީ އެއީއެވެ.","",""],["₅ سورة المائدة","120","لِلَّهِ مُلۡكُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ وَمَا فِيهِنَّۚ وَهُوَ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرُۢ ١٢٠","لله ملك السماوات والأرض وما فيهن وهو على كل شيء قدير","އުޑުތަކާއި، ބިމާއި، އެތަންތާނގައި ވާހާ ތަކެއްޗެއްގެ މިލްކުވެރިކަންވަނީ، ﷲއަށެވެ. އަދި އެކަލާނގެއީ، ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","1","بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ\n<br><br>\nٱلۡحَمۡدُ لِلَّهِ ٱلَّذِي خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضَ وَجَعَلَ ٱلظُّلُمَٰتِ وَٱلنُّورَۖ ثُمَّ ٱلَّذِينَ كَفَرُواْ بِرَبِّهِمۡ يَعۡدِلُونَ ١","بسم الله الرحمن الرحيم الحمد لله الذي خلق السماوات والأرض وجعل الظلمات والنور ثم الذين كفروا بربهم يعدلون","ހަމްދު ހުރީ އުޑުތަކާއި ބިންހައްދަވައި އަނދިރިކަމާއި، އަލިކަންލެއްވި ﷲއަށެވެ. ދެންވެސް ކާފިރުވި މީހުން އެއުރެންގެ ވެރިރަސްކަލާނގެއާއި، އެހެންތަކެއްޗާ ހަމަހަމަކޮށް ޝަރީކުކުރެތެވެ.","",""],["₆ سورة الأنعام","2","هُوَ ٱلَّذِي خَلَقَكُم مِّن طِينٖ ثُمَّ قَضَىٰٓ أَجَلٗاۖ وَأَجَلٞ مُّسَمًّى عِندَهُۥۖ ثُمَّ أَنتُمۡ تَمۡتَرُونَ ٢","هو الذي خلقكم من طين ثم قضى أجلا وأجل مسمى عنده ثم أنتم تمترون","އެކަލާނގެއީ، މަށިން ތިޔަބައިމީހުން ހެއްދެވި ރަސްކަލާނގެއެވެ. ދެން (ތިޔަބައިމީހުން މަރުވުމަށް) އަޖަލެއް ކަނޑައަޅުއްވައި، ނިޔާކުރެއްވިއެވެ. އަދި (ތިޔަބައިމީހުން އަލުން ދިރުއްވުމަށް) އެކަލާނގެ ހަޒުރަތުގައި ކަނޑައަޅުއްވާފައިވާ އަޖަލެއް ވެއެވެ. ދެން އެއަށްފަހު (ވެސް) ތިޔަބައިމީހުން ޝައްކުކުރަމުއެވެ.","",""],["₆ سورة الأنعام","3","وَهُوَ ٱللَّهُ فِي ٱلسَّمَٰوَٰتِ وَفِي ٱلۡأَرۡضِ يَعۡلَمُ سِرَّكُمۡ وَجَهۡرَكُمۡ وَيَعۡلَمُ مَا تَكۡسِبُونَ ٣","وهو الله في السماوات وفي الأرض يعلم سركم وجهركم ويعلم ما تكسبون","އެކަލާނގެއީ، އުޑުތަކާއި ބިމުގައި (އަޅުކަންވެވުން ހައްގު ވެގެން) ވާ، ﷲއެވެ. ތިޔަބައިމީހުން ސިއްރުކުރާ ކަންތަކާއި، ތިޔަބައިމީހުން ފާޅުކުރާ ކަންތައް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަދި ތިޔަބައިމީހުން، ހޯދައިގަންނަ ކަންތައް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ.","",""],["₆ سورة الأنعام","4","وَمَا تَأۡتِيهِم مِّنۡ ءَايَةٖ مِّنۡ ءَايَٰتِ رَبِّهِمۡ إِلَّا كَانُواْ عَنۡهَا مُعۡرِضِينَ ٤","وما تأتيهم من آية من آيات ربهم إلا كانوا عنها معرضين","އެ އާޔަތްތަކަށް އެއުރެން ފުރަގަސްދޭކަމުގައިވި އާޔަތް ތަކެއް މެނުވީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ އާޔަތްތަކުގެ ތެރެއިން އެއްވެސް އާޔަތެއް އެއުރެންގެ ގާތަކަށް ނާދެތެވެ.","",""],["₆ سورة الأنعام","5","فَقَدۡ كَذَّبُواْ بِٱلۡحَقِّ لَمَّا جَآءَهُمۡ فَسَوۡفَ يَأۡتِيهِمۡ أَنۢبَـٰٓؤُاْ مَا كَانُواْ بِهِۦ يَسۡتَهۡزِءُونَ ٥","فقد كذبوا بالحق لما جاءهم فسوف يأتيهم أنباء ما كانوا به يستهزئون","ފަހެ، ހަމަކަށަވަރުން، ހައްގު ބަސްފުޅު އެއުރެންގެ ގާތަށް އައިހިނދު، އެއުރެން އެބަސް ދޮގުކުޅައެވެ. ފަހެ، އެއުރެން އެކަމަކަށް ފުރައްސާރަކޮށް އުޅުނު ކަންތަކުގެ ޚަބަރުތައް އަދި ފަހުން އެއުރެންގެ ގާތަށް އަންނާނެތެވެ.","",""],["₆ سورة الأنعام","6","أَلَمۡ يَرَوۡاْ كَمۡ أَهۡلَكۡنَا مِن قَبۡلِهِم مِّن قَرۡنٖ مَّكَّنَّـٰهُمۡ فِي ٱلۡأَرۡضِ مَا لَمۡ نُمَكِّن لَّكُمۡ وَأَرۡسَلۡنَا ٱلسَّمَآءَ عَلَيۡهِم مِّدۡرَارٗا وَجَعَلۡنَا ٱلۡأَنۡهَٰرَ تَجۡرِي مِن تَحۡتِهِمۡ فَأَهۡلَكۡنَٰهُم بِذُنُوبِهِمۡ وَأَنشَأۡنَا مِنۢ بَعۡدِهِمۡ قَرۡنًا ءَاخَرِينَ ٦","ألم يروا كم أهلكنا من قبلهم من قرن مكناهم في الأرض ما لم نمكن لكم وأرسلنا السماء عليهم مدرارا وجعلنا الأنهار تجري من تحتهم فأهلكناهم بذنوبهم وأنشأنا من بعدهم قرنا آخرين","އެއުރެންގެ ކުރިން ތިމަންރަސްކަލާނގެ ހަލާކުކުރައްވައި ނެތިކުރެއްވީ ކިތައްކިތައް އުއްމަތްގެ މީހުންކަން އެއުރެންނަށް ނޭނގެނީހެއްޔެވެ؟ ތިޔަބައިމީހުންނަށް، ތިމަންރަސްކަލާނގެ ނުދެއްވާ ތަނަވަސްކަމާއި، ބާރު، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ބިމުގައި ދެއްވީމެވެ. އަދި ބޯކޮށްވެހޭ ވާރޭ އެއުރެންނަށް އުޑުން ތިމަންރަސްކަލާނގެ ފޮނުއްވީމެވެ. އަދި އެއުރެންގެ ދަށުން ހިނގަހިނގާ ހުންނަ ފެންކޯރުތައް ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ. ދެން އެއުރެންގެ ފާފަތަކުގެ ސަބަބުން ތިމަންރަސްކަލާނގެ އެއުރެން ހަލާކު ކުރައްވައި ނެތިކުރެއްވީމެވެ. އަދި އެއުރެންގެ ފަހުން ތިމަންރަސްކަލާނގެ އެހެން ޖީލެއްގެ ބަޔަކު އުފެއްދެވީމެވެ.","",""],["₆ سورة الأنعام","7","وَلَوۡ نَزَّلۡنَا عَلَيۡكَ كِتَٰبٗا فِي قِرۡطَاسٖ فَلَمَسُوهُ بِأَيۡدِيهِمۡ لَقَالَ ٱلَّذِينَ كَفَرُوٓاْ إِنۡ هَٰذَآ إِلَّا سِحۡرٞ مُّبِينٞ ٧","ولو نزلنا عليك كتابا في قرطاس فلمسوه بأيديهم لقال الذين كفروا إن هذا إلا سحر مبين","އަދި ކަރުދާހެއްގައި ލިޔުއްވާފައިވާ ފޮތެއް، ކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ ބާވައިލެއްވިޔަސް ދެން އެއުރެންގެ އަތްތަކުން އެފޮތުގައި ބީހުނަސް، ފާޅުވެގެންވާ ޖާދޫއެއްކަމުގައި މެނުވީ ތިޔަފޮތް ނުވެޔޭ ކާފިރު ވީ މީހުން ބުނީހެވެ.","",""],["₆ سورة الأنعام","8","وَقَالُواْ لَوۡلَآ أُنزِلَ عَلَيۡهِ مَلَكٞۖ وَلَوۡ أَنزَلۡنَا مَلَكٗا لَّقُضِيَ ٱلۡأَمۡرُ ثُمَّ لَا يُنظَرُونَ ٨","وقالوا لولا أنزل عليه ملك ولو أنزلنا ملكا لقضي الأمر ثم لا ينظرون","އަދި އެއުރެން ބުނެފޫއެވެ. އެކަލޭގެފާނުގެ އަރިހަށް މަލާއިކަތަކު ބާވައިލައްވާފައި ނުވަނީ ކީއްވެގެންބާވައެވެ؟ (ދަންނާށެވެ!) ތިމަންރަސްކަލާނގެ މަލާއިކަތަކު ބާވައިލެއްވިނަމަ، ކަންތަކުގެ ނިޔާކަނޑައެޅި ނިމިއްޖައީހެވެ. (އެބަހީ: ކޯފާލައްވައި އެންމެން ނެތިކުރައްވައިފީހެވެ.) ދެން (އެއަށްފަހު) އެއުރެންނަކަށް މުހުލަތެއް ނުދެއްވާ ހުށްޓެވެ.","",""],["₆ سورة الأنعام","9","وَلَوۡ جَعَلۡنَٰهُ مَلَكٗا لَّجَعَلۡنَٰهُ رَجُلٗا وَلَلَبَسۡنَا عَلَيۡهِم مَّا يَلۡبِسُونَ ٩","ولو جعلناه ملكا لجعلناه رجلا وللبسنا عليهم ما يلبسون","ތިމަންރަސްކަލާނގެ ރަސޫލަކީ، މަލާއިކަތަކު ކަމުގައި ލެއްވިނަމަ، އެ މަލާއިކަތަކު، ފިރިހެން އިންސާނެއްގެ ސިފައިގައި ލެއްވީމުހެވެ. އަދި އެއުރެން އޮޅުވައިލާކަންތައް (އޭރުންވެސް) އެއުރެންނަށް އޮޅުވައިލާގޮތް ތިމަންރަސްކަލާނގެ ހެއްދެވީމުހެވެ. (ނޯޓު: މި އާޔަތުން އެ އަންގަވަނީ މާތްﷲ، ރަސޫލުކަމާއިގެން މަލާއިކަތަކު ފޮނުއްވިނަމަ އެ މަލާއިކަތަކު ފޮނުއްވީހީ، ފިރިހެން އިންސާނެއްގެ ސިފައިގައެވެ. އެހެނީ މަލާއިކަތެއްގެ އަޞްލު ސޫރައިގައި ފޮނުއްވިނަމަ، އެ މަލާއިކަތަކާ ބައްދަލުކޮށް ވާހަކަދައްކައި އުޅުމަކީ، އާދަމުގެދަރިންނަށް ކުޅަދާނަވެގެންވާ ކަމެއްކަމުގައި ނުވީހެވެ. އެހެންކަމުން، އެއުރެން އޮޅުވައިލަން އުޅުނު އޮޅުން އެއުރެންނަށް އޮޅޭނޭގޮތް ﷲ ހެއްދެވީއެވެ.)","",""],["₆ سورة الأنعام","10","وَلَقَدِ ٱسۡتُهۡزِئَ بِرُسُلٖ مِّن قَبۡلِكَ فَحَاقَ بِٱلَّذِينَ سَخِرُواْ مِنۡهُم مَّا كَانُواْ بِهِۦ يَسۡتَهۡزِءُونَ ١٠","ولقد استهزئ برسل من قبلك فحاق بالذين سخروا منهم ما كانوا به يستهزئون","އަދި ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ކުރީގެ ރަސޫލުންނަށްވެސް ފުރައްސާރަކުރިއެވެ. ފަހެ، އެ ރަސޫލުންނަށް ފުރައްސާރަކޮށް އުޅުނު މީހުން ކުރަމުންގެންދިޔަ ފުރައްސާރައިގެ ކަންތައް (އެބަހީ: އެކަމުގެ ކޯފާއާއި އަޒާބު) އެއުރެން ވަށައިލިއެވެ.","",""],["₆ سورة الأنعام","11","قُلۡ سِيرُواْ فِي ٱلۡأَرۡضِ ثُمَّ ٱنظُرُواْ كَيۡفَ كَانَ عَٰقِبَةُ ٱلۡمُكَذِّبِينَ ١١","قل سيروا في الأرض ثم انظروا كيف كان عاقبة المكذبين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ބިމުގައި ދަތުރުފަތުރުކޮށް އުޅޭށެވެ! ދެން އެއަށްފަހު ދޮގުކުޅަ މީހުންގެ ނަތީޖާ އޮތީ ކިހިނަކުންކަން ތިޔަބައިމީހުން ދެކޭށެވެ!","",""],["₆ سورة الأنعام","12","قُل لِّمَن مَّا فِي ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِۖ قُل لِّلَّهِۚ كَتَبَ عَلَىٰ نَفۡسِهِ ٱلرَّحۡمَةَۚ لَيَجۡمَعَنَّكُمۡ إِلَىٰ يَوۡمِ ٱلۡقِيَٰمَةِ لَا رَيۡبَ فِيهِۚ ٱلَّذِينَ خَسِرُوٓاْ أَنفُسَهُمۡ فَهُمۡ لَا يُؤۡمِنُونَ ١٢","قل لمن ما في السماوات والأرض قل لله كتب على نفسه الرحمة ليجمعنكم إلى يوم القيامة لا ريب فيه الذين خسروا أنفسهم فهم لا يؤمنون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އުޑުތަކާއި ބިމުގައިވާ ތަކެތި މިލްކުވެގެންވަނީ، ކާކަށްހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲއަށެވެ. އެކަލާނގެ އަމިއްލަ ޛާތު ފުޅުގެ މައްޗަށް ރަހުމަތް ކަނޑައަޅުއްވައި ލިޔުއްވާފައިވެއެވެ. (އެބަހީ: އަޅުތަކުންނަށް ރަހުމަތް ވަންތަވެވޮޑިގަތުމަކީ އެކަލާނގެ ޛާތު ފުޅަށް އެކަލާނގެ ލާޒިމުކުރައްވާފައިވާ ކަމެކެވެ.) ހަމަކަށަވަރުން، އެކަލާނގެ ތިޔަބައިމީހުން ގިޔާމަތް ދުވަހަށް އެއްކުރައްވާނެތެވެ. އެކަމާމެދު ޝައްކެއް ނެތެވެ. އެއުރެންގެ އަމިއްލަ ނަފްސުތައް ނަގައިލި މީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެން އީމާނެއް ނުވާނެތެވެ.","",""],["₆ سورة الأنعام","13","۞وَلَهُۥ مَا سَكَنَ فِي ٱلَّيۡلِ وَٱلنَّهَارِۚ وَهُوَ ٱلسَّمِيعُ ٱلۡعَلِيمُ ١٣","وله ما سكن في الليل والنهار وهو السميع العليم","ރެއާއި ދުވާލުގެތެރޭ އުޅޭހައި ތަކެތި، މިލްކުވެގެންވަނީ އެކަލާނގެއަށެވެ. އެކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","14","قُلۡ أَغَيۡرَ ٱللَّهِ أَتَّخِذُ وَلِيّٗا فَاطِرِ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ وَهُوَ يُطۡعِمُ وَلَا يُطۡعَمُۗ قُلۡ إِنِّيٓ أُمِرۡتُ أَنۡ أَكُونَ أَوَّلَ مَنۡ أَسۡلَمَۖ وَلَا تَكُونَنَّ مِنَ ٱلۡمُشۡرِكِينَ ١٤","قل أغير الله أتخذ وليا فاطر السماوات والأرض وهو يطعم ولا يطعم قل إني أمرت أن أكون أول من أسلم ولا تكونن من المشركين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެހީތެރިޔަކު ކަމުގައި ތިމަންކަލޭގެފާނު ހިއްޕަވަންވީ، އިސްވެދިޔަ މިސާލެއް ނެތި އުޑުތަކާއި ބިންހެއްދެވި ﷲ ނޫން އެހެންފަރާތެއް ހެއްޔެވެ؟ ރިޒްގު ދެއްވަނީ އެކަލާނގެއެވެ. ރިޒްގު ލިބުމަކަށް އެކަލާނގެ ބޭނުންވެވޮޑިގެނެއް ނުވެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އިސްލާމް ވީ އެންމެ ފުރަތަމަ މީހާ ކަމުގައިވުމަށް ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނަށް އަމުރު ކުރައްވާފައިވެއެވެ. އަދި ހަމަކަށަވަރުން، ޝަރީކުކުރާ މީހުންގެ ތެރެއިން ކަލޭގެފާނު ވެވަޑައިނުގަންނަވާށެވެ!","",""],["₆ سورة الأنعام","15","قُلۡ إِنِّيٓ أَخَافُ إِنۡ عَصَيۡتُ رَبِّي عَذَابَ يَوۡمٍ عَظِيمٖ ١٥","قل إني أخاف إن عصيت ربي عذاب يوم عظيم","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް ތިމަންކަލޭގެފާނު އުރެދިއްޖެނަމަ، ބޮޑުވެގެންވާ ދުވަހެއްގެ އަޒާބަށް ހަމަކަށަވަރުން ތިމަންކަލޭގެފާނު ބިރުފުޅުގަނެއެވެ.","",""],["₆ سورة الأنعام","16","مَّن يُصۡرَفۡ عَنۡهُ يَوۡمَئِذٖ فَقَدۡ رَحِمَهُۥۚ وَذَٰلِكَ ٱلۡفَوۡزُ ٱلۡمُبِينُ ١٦","من يصرف عنه يومئذ فقد رحمه وذلك الفوز المبين","އެދުވަހުން، އެމީހެއްގެ ކިބައިން އެ އަޒާބު ދުރުކުރައްވާފައިވާ މީހާ (ދަންނަށާވެ!) ފަހެ، ހަމަކަށަވަރުން އެމީހަކަށް އެކަލާނގެ ރަހުމަތް ލައްވައިފިއެވެ. އަދި ބަޔާން ވެގެންވާ ނަސީބު ލިބުމަކީ އެއީއެވެ.","",""],["₆ سورة الأنعام","17","وَإِن يَمۡسَسۡكَ ٱللَّهُ بِضُرّٖ فَلَا كَاشِفَ لَهُۥٓ إِلَّا هُوَۖ وَإِن يَمۡسَسۡكَ بِخَيۡرٖ فَهُوَ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٞ ١٧","وإن يمسسك الله بضر فلا كاشف له إلا هو وإن يمسسك بخير فهو على كل شيء قدير","އަދި ﷲ، ތިބާޔަށް ގެއްލުމެއް މެދުވެރިކުރައްވާނަމަ، އެކަލާނގެ މެނުވީ އެކަން ފިއްލަވާނެ އެހެންފަރާތެއް ނުވެއެވެ. އަދި އެކަލާނގެ ތިބާޔަށް ހެޔޮގޮތެއް މެދުވެރިކުރައްވާނަމަ، (އެކަން ދުރުކުރާނޭ އެހެންފަރާތެއް ނުވެއެވެ.) ފަހެ، އެކަލާނގެއީ ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","18","وَهُوَ ٱلۡقَاهِرُ فَوۡقَ عِبَادِهِۦۚ وَهُوَ ٱلۡحَكِيمُ ٱلۡخَبِيرُ ١٨","وهو القاهر فوق عباده وهو الحكيم الخبير","އަދި އެކަލާނގެއީ، އެކަލާނގެ އަޅުތަކުންގެ މައްޗަށް ގަދަވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","19","قُلۡ أَيُّ شَيۡءٍ أَكۡبَرُ شَهَٰدَةٗۖ قُلِ ٱللَّهُۖ شَهِيدُۢ بَيۡنِي وَبَيۡنَكُمۡۚ وَأُوحِيَ إِلَيَّ هَٰذَا ٱلۡقُرۡءَانُ لِأُنذِرَكُم بِهِۦ وَمَنۢ بَلَغَۚ أَئِنَّكُمۡ لَتَشۡهَدُونَ أَنَّ مَعَ ٱللَّهِ ءَالِهَةً أُخۡرَىٰۚ قُل لَّآ أَشۡهَدُۚ قُلۡ إِنَّمَا هُوَ إِلَٰهٞ وَٰحِدٞ وَإِنَّنِي بَرِيٓءٞ مِّمَّا تُشۡرِكُونَ ١٩","قل أي شيء أكبر شهادة قل الله شهيد بيني وبينكم وأوحي إلي هذا القرآن لأنذركم به ومن بلغ أئنكم لتشهدون أن مع الله آلهة أخرى قل لا أشهد قل إنما هو إله واحد وإنني بريء مما تشركون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހެކިބަހެއްގެގޮތުން އެންމެބޮޑީ، ކޮން އެއްޗެއްހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނާއި ތިޔަބައިމީހުންނާ ދެމެދު ﷲ ހެކިވެވޮޑިގެންވެއެވެ. ތިޔަބައިމީހުންނަށާއި، އެމީހަކާ ހަމަޔަށް ފޯރިމީހަކަށް އެއިން ތިމަންކަލޭގެފާނު އިންޒާރުކުރެއްވުމަށް ތިމަންކަލޭގެފާނަށް މި ގުރްއާން، ވަހީކުރެއްވިއެވެ. ހަމަކަށަވަރުން، ﷲއާއެކުގައި އެހެން އިލާހުންތަކެއް ވާކަމަށް ތިޔަބައިމީހުން ހެކިވަނީ ހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނު (އެކަމަކަށް) ހެތްކެއް ނުވަމެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަލާނގެއީ، ހަމަކަށަވަރުން، އެއްކައުވަންތަ ކަލާނގެއެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނު ވަނީ، ތިޔަބައިމީހުން ޝަރީކުކުރާ ތަކެތިން ބަރީއަވެގެންނެވެ.","",""],["₆ سورة الأنعام","20","ٱلَّذِينَ ءَاتَيۡنَٰهُمُ ٱلۡكِتَٰبَ يَعۡرِفُونَهُۥ كَمَا يَعۡرِفُونَ أَبۡنَآءَهُمُۘ ٱلَّذِينَ خَسِرُوٓاْ أَنفُسَهُمۡ فَهُمۡ لَا يُؤۡمِنُونَ ٢٠","الذين آتيناهم الكتاب يعرفونه كما يعرفون أبناءهم الذين خسروا أنفسهم فهم لا يؤمنون","ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ފޮތް ދެއްވި މީހުން، އެއުރެންގެ ދަރިން ދަންނަ ފަދައިން އެއުރެން އެކަލޭގެފާނު (އެބަހީ: މުޙައްމަދުގެފާނު) ދަނެތެވެ. (އެބަހީ: ތައުރާތާއި، އިންޖީލުގެ އަހުލުވެރިން، މުޙައްމަދުގެފާނަކީ ރަސޫލަކުކަން ރަނގަޅަށް ދަނެތެވެ.) އެއުރެންގެ ނަފްސުތައް ގެއްލެނި ކުޅަމީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެން އީމާނެއް ނުވާނެތެވެ.","",""],["₆ سورة الأنعام","21","وَمَنۡ أَظۡلَمُ مِمَّنِ ٱفۡتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَوۡ كَذَّبَ بِـَٔايَٰتِهِۦٓۚ إِنَّهُۥ لَا يُفۡلِحُ ٱلظَّـٰلِمُونَ ٢١","ومن أظلم ممن افترى على الله كذبا أو كذب بآياته إنه لا يفلح الظالمون","ﷲއާމެދު ހަދައިގެން ދޮގުބުނި މީހަކަށްވުރެން ނުވަތަ، އެކަލާނގެ އާޔަތްތައް ދޮގުކުޅަ މީހަކަށްވުރެން، އަނިޔާވެރިކަންބޮޑީ ކާކުހެއްޔެވެ؟ ހަމަކަށަވަރުން، އަނިޔާވެރިންނެއް ނުދިނޭނެތެވެ.","",""],["₆ سورة الأنعام","22","وَيَوۡمَ نَحۡشُرُهُمۡ جَمِيعٗا ثُمَّ نَقُولُ لِلَّذِينَ أَشۡرَكُوٓاْ أَيۡنَ شُرَكَآؤُكُمُ ٱلَّذِينَ كُنتُمۡ تَزۡعُمُونَ ٢٢","ويوم نحشرهم جميعا ثم نقول للذين أشركوا أين شركاؤكم الذين كنتم تزعمون","ތިމަންރަސްކަލާނގެ އެއުރެން އެންމެން އެއްތަނަކަށް އެއްކުރައްވާދުވަސް (ހަނދުމަކުރާށެވެ!) ދެން، ޝަރީކުކުޅަ މީހުންނަށް ތިމަންރަސްކަލާނގެ ވަހީކުރައްވާހުށީމެވެ. ތިޔަބައިމީހުން ޝަރީކުން ކަމުގައި ހީކޮށްގެން އުޅުނު ތަކެތި ކޮބައިހެއްޔެވެ؟","",""],["₆ سورة الأنعام","23","ثُمَّ لَمۡ تَكُن فِتۡنَتُهُمۡ إِلَّآ أَن قَالُواْ وَٱللَّهِ رَبِّنَا مَا كُنَّا مُشۡرِكِينَ ٢٣","ثم لم تكن فتنتهم إلا أن قالوا والله ربنا ما كنا مشركين","ދެން ތިމަންމެންގެ ވެރި ﷲ ގަންދީ ބުނަމުއޭ، ޝަރީކުކުޅަ ބަޔަކު ކަމުގައި ތިމަންމެން ނުވަމުއޭ، އެއުރެން ބުނުން ނޫން ބަހަނާއެއް އެއުރެން ދައްކާކަށް ނެތެވެ.","",""],["₆ سورة الأنعام","24","ٱنظُرۡ كَيۡفَ كَذَبُواْ عَلَىٰٓ أَنفُسِهِمۡۚ وَضَلَّ عَنۡهُم مَّا كَانُواْ يَفۡتَرُونَ ٢٤","انظر كيف كذبوا على أنفسهم وضل عنهم ما كانوا يفترون","އެއުރެންގެ އަމިއްލަ ނަފްސުތަކުގެ މައްޗަށް ދޮގުހެދީ ކިހިނެއްކަން އަދި އެއުރެން ދޮގުން އުފައްދައި އުޅުނު ތަކެތި އެއުރެންގެ ކިބައިން ގެއްލިގެންދިޔައީ ކިހިނަކުންކަން ތިބާ ދެކޭށެވެ!","",""],["₆ سورة الأنعام","25","وَمِنۡهُم مَّن يَسۡتَمِعُ إِلَيۡكَۖ وَجَعَلۡنَا عَلَىٰ قُلُوبِهِمۡ أَكِنَّةً أَن يَفۡقَهُوهُ وَفِيٓ ءَاذَانِهِمۡ وَقۡرٗاۚ وَإِن يَرَوۡاْ كُلَّ ءَايَةٖ لَّا يُؤۡمِنُواْ بِهَاۖ حَتَّىٰٓ إِذَا جَآءُوكَ يُجَٰدِلُونَكَ يَقُولُ ٱلَّذِينَ كَفَرُوٓاْ إِنۡ هَٰذَآ إِلَّآ أَسَٰطِيرُ ٱلۡأَوَّلِينَ ٢٥","ومنهم من يستمع إليك وجعلنا على قلوبهم أكنة أن يفقهوه وفي آذانهم وقرا وإن يروا كل آية لا يؤمنوا بها حتى إذا جاءوك يجادلونك يقول الذين كفروا إن هذا إلا أساطير الأولين","އަދި ކަލޭގެފާނަށް ކަނުލައިއަހާ މީހުން، އެއުރެންގެ ތެރެއިންވެއެވެ. އަދި އެއުރެންނަށް އެ ވިދާޅުވާ އެއްޗެއް ނުވިސްނުމަށްޓަކައި، އެއުރެންގެ ހިތްތަކުގެ މަތީގައި ފަރުދާއެއް ލެއްވީމެވެ. އަދި އެއުރެންގެ ކަންފަތްތަކުގައި ބީރުކަމެއްލެއްވީމެވެ. އަދި އެއުރެންނަށް ކޮންމެ އާޔަތެއް ފެނުނަސް، އެއުރެން އެއަކަށް އީމާނެއް ނުވެތެވެ. އެހެންކަމާއެކު، އެއުރެން ކަލޭގެފާނާ ޖަދަލުކުރުމަށް ކަލޭގެފާނުގެ އަރިހަށް އަތުވެއްޖެހިނދަކު ކާފިރުވި މީހުން ބުނެތެވެ. ތިޔައީ އެވޭލާ މީހުންގެ ފުލޯކު ވާހަކަތަކެއް ކަމުގައި މެނުވީ ނުވެއެވެ.","",""],["₆ سورة الأنعام","26","وَهُمۡ يَنۡهَوۡنَ عَنۡهُ وَيَنۡـَٔوۡنَ عَنۡهُۖ وَإِن يُهۡلِكُونَ إِلَّآ أَنفُسَهُمۡ وَمَا يَشۡعُرُونَ ٢٦","وهم ينهون عنه وينأون عنه وإن يهلكون إلا أنفسهم وما يشعرون","އަދި އެއުރެން އެ ގުރްއާނަށް ތަބާ ވުން (މީސްތަކުންނަށް) މަނާކުރެތެވެ. އަދި އެއުރެން އެއިން ދުރުވެގަނެތެވެ. (އެކަމުން) އެއުރެންނަށް ނޭނގިތިބެ އަމިއްލަ ނަފްސުތައް މެނުވީ އެއުރެން ހަލާކެއް ނުކުރެތެވެ.","",""],["₆ سورة الأنعام","27","وَلَوۡ تَرَىٰٓ إِذۡ وُقِفُواْ عَلَى ٱلنَّارِ فَقَالُواْ يَٰلَيۡتَنَا نُرَدُّ وَلَا نُكَذِّبَ بِـَٔايَٰتِ رَبِّنَا وَنَكُونَ مِنَ ٱلۡمُؤۡمِنِينَ ٢٧","ولو ترى إذ وقفوا على النار فقالوا يا ليتنا نرد ولا نكذب بآيات ربنا ونكون من المؤمنين","އެއުރެން ނަރަކައިގެ ކުރިމަތީގައި ބައިތިއްބަވާހިނދު ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނެ ނަމައެވެ. ދެން އެއުރެން ބުނާނެތެވެ. އޭ ސަހަރޯއެވެ! ތިމަންމެން (ދުނިޔެއަށް) އަނބުރާ ފޮނުއްވާނެނަމަ ކޮންފަދަހެއްޔެވެ؟ އޭރުން ތިމަންމެންގެ ވެރިރަސްކަލާނގެ އާޔަތްތައް ދޮގެއް ނުކުރާނޫއެވެ. އަދި އީމާންވި މީހުންގެ ތެރެއިން ތިމަންމެން ވާނޫއެވެ.","",""],["₆ سورة الأنعام","28","بَلۡ بَدَا لَهُم مَّا كَانُواْ يُخۡفُونَ مِن قَبۡلُۖ وَلَوۡ رُدُّواْ لَعَادُواْ لِمَا نُهُواْ عَنۡهُ وَإِنَّهُمۡ لَكَٰذِبُونَ ٢٨","بل بدا لهم ما كانوا يخفون من قبل ولو ردوا لعادوا لما نهوا عنه وإنهم لكاذبون","އަދި ކިއެއްތަ! އެއުރެން ކުރިން ވަންހަނާކޮށްގެން އުޅުނު ކަންތައް އެއުރެންނަށް ފާޅުވިއެވެ. އަދި އެއުރެން (ދުނިޔެއަށް) އަލުން ފޮނުއްވިނަމަ، އެއުރެންނަށް ނަހީކުރެއްވި ކަންތަކަށް އެއުރެން އެނބުރި ހިނގައްޖައީހެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެންނަކީ ދޮގުހަދާ ބަޔަކުކަން ކަށަވަރެވެ.","",""],["₆ سورة الأنعام","29","وَقَالُوٓاْ إِنۡ هِيَ إِلَّا حَيَاتُنَا ٱلدُّنۡيَا وَمَا نَحۡنُ بِمَبۡعُوثِينَ ٢٩","وقالوا إن هي إلا حياتنا الدنيا وما نحن بمبعوثين","އަދި އެއުރެން ބުނެފޫއެވެ. ތިމަންމެންގެ ދުނިޔޭގެ ދިރިތިބުން މެނުވީ، އެހެން ދިރިތިބުމެއް ނެތެވެ. އަދި އަލުން ދިރުއްވައި ފޮނުއްވާނެ ބަޔަކު ކަމުގައި ތިމަންމެން ނުވަމުއެވެ.","",""],["₆ سورة الأنعام","30","وَلَوۡ تَرَىٰٓ إِذۡ وُقِفُواْ عَلَىٰ رَبِّهِمۡۚ قَالَ أَلَيۡسَ هَٰذَا بِٱلۡحَقِّۚ قَالُواْ بَلَىٰ وَرَبِّنَاۚ قَالَ فَذُوقُواْ ٱلۡعَذَابَ بِمَا كُنتُمۡ تَكۡفُرُونَ ٣٠","ولو ترى إذ وقفوا على ربهم قال أليس هذا بالحق قالوا بلى وربنا قال فذوقوا العذاب بما كنتم تكفرون","އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި އެއުރެން ބައިތިއްބަވާހިނދު ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނެ ނަމައެވެ. (އެހިނދު) އެކަލާނގެ ވަހީކުރައްވާނެތެވެ. މިއީ ތެދު ހަގީގަތްކަމުގައި ނުވޭހެއްޔެވެ؟ އެއުރެން ދަންނަވާނެތެވެ. ތިމަންމެންގެ ވެރިރަސްކަލާނގެ ގަންދީ ބުނަމެވެ. ނޫނެކެވެ. އެކަލާނގެ ވަހީކުރައްވާނެތެވެ. ފަހެ، ތިޔަބައިމީހުން ކާފިރުވެ އުޅުނުކަމުގެ ސަބަބުން ތިޔަބައިމީހުން އަޒާބުގެ ރަހަ ލިބިގަންނާށެވެ!","",""],["₆ سورة الأنعام","31","قَدۡ خَسِرَ ٱلَّذِينَ كَذَّبُواْ بِلِقَآءِ ٱللَّهِۖ حَتَّىٰٓ إِذَا جَآءَتۡهُمُ ٱلسَّاعَةُ بَغۡتَةٗ قَالُواْ يَٰحَسۡرَتَنَا عَلَىٰ مَا فَرَّطۡنَا فِيهَا وَهُمۡ يَحۡمِلُونَ أَوۡزَارَهُمۡ عَلَىٰ ظُهُورِهِمۡۚ أَلَا سَآءَ مَا يَزِرُونَ ٣١","قد خسر الذين كذبوا بلقاء الله حتى إذا جاءتهم الساعة بغتة قالوا يا حسرتنا على ما فرطنا فيها وهم يحملون أوزارهم على ظهورهم ألا ساء ما يزرون","ﷲއާ ބައްދަލުވާނެ ކަމާމެދު އިންކާރު ކޮށް، ދޮގުކުޅަ މީހުން ގެއްލި ހަލާކުވެއްޖެކަން ކަށަވަރެވެ. ގިޔާމަތްގެ ވަގުތު ކުއްލިއަކަށް އެއުރެންގެ ގާތަށް އަންނަހިނދު އެއުރެން ބުނާނެތެވެ. އަހުރެމެން އެދުވަހާމެދު ކުޅަ އިހުމާލުގެ މައްޗަށް އަހުރެމެންނަށް ހުރި ހިތާމައެއްގެ ބޮޑުކަމާއެވެ! އެއުރެން އެހިނދު ތިބޭނީ އެއުރެންގެ ފާފަތައް އެއުރެންގެ ބުރިކަށިތަކުގެ މަތީގައި އުފުލައިގެންނެވެ. ދަންނާށެވެ! އެއުރެން އުފުލާ ކުށްތަކުގެ ނުބައިކަމާއެވެ.","",""],["₆ سورة الأنعام","32","وَمَا ٱلۡحَيَوٰةُ ٱلدُّنۡيَآ إِلَّا لَعِبٞ وَلَهۡوٞۖ وَلَلدَّارُ ٱلۡأٓخِرَةُ خَيۡرٞ لِّلَّذِينَ يَتَّقُونَۚ أَفَلَا تَعۡقِلُونَ ٣٢","وما الحياة الدنيا إلا لعب ولهو وللدار الآخرة خير للذين يتقون أفلا تعقلون","ދުނިޔޭގެ ދިރިއުޅުމަކީ ކުޅިވަރެއްކަމުގައްޔާއި، މަޖަލެއްކަމުގައި މެނުވީ ނުވެއެވެ. ތަގުވާވެރިވާ މީހުންނަށް އާޚިރަތްގެ ގޮވަތި ހެޔޮކަން މާބޮޑެވެ. ފަހެ، ތިޔަބައިމީހުންނަކަށް ނުވިސްނޭހެއްޔެވެ؟","",""],["₆ سورة الأنعام","33","قَدۡ نَعۡلَمُ إِنَّهُۥ لَيَحۡزُنُكَ ٱلَّذِي يَقُولُونَۖ فَإِنَّهُمۡ لَا يُكَذِّبُونَكَ وَلَٰكِنَّ ٱلظَّـٰلِمِينَ بِـَٔايَٰتِ ٱللَّهِ يَجۡحَدُونَ ٣٣","قد نعلم إنه ليحزنك الذي يقولون فإنهم لا يكذبونك ولكن الظالمين بآيات الله يجحدون","އެއުރެން (އެބަހީ: ކާފިރުން) ބުނާބުނުމުގެ ސަބަބުން ކަލޭގެފާނަށް މޮޅިވެރިކަން ލިބިވަޑައިގަންނަވަމުންދާކަން ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގެންވަމެވެ. ފަހެ، އެއުރެންނަށް އެ ދޮގުކުރެވެނީ ކަލޭގެފާނެއް ނޫންކަން ކަށަވަރެވެ. އެހެނެއްކަމަކު އަނިޔާވެރިން ދެކޮޅުހަދަނީ ﷲގެ އާޔަތް ތަކާމެދުގައެވެ.","",""],["₆ سورة الأنعام","34","وَلَقَدۡ كُذِّبَتۡ رُسُلٞ مِّن قَبۡلِكَ فَصَبَرُواْ عَلَىٰ مَا كُذِّبُواْ وَأُوذُواْ حَتَّىٰٓ أَتَىٰهُمۡ نَصۡرُنَاۚ وَلَا مُبَدِّلَ لِكَلِمَٰتِ ٱللَّهِۚ وَلَقَدۡ جَآءَكَ مِن نَّبَإِيْ ٱلۡمُرۡسَلِينَ ٣٤","ولقد كذبت رسل من قبلك فصبروا على ما كذبوا وأوذوا حتى أتاهم نصرنا ولا مبدل لكلمات الله ولقد جاءك من نبإ المرسلين","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ކުރިންވެސް ރަސޫލުންތަކެއް ދޮގުކޮށްފައިވެއެވެ. ދެން އެ ދޮގުކުރިކަމުގެ މައްޗަށް އެ ރަސޫލުން ކެތްކުރެއްވިއެވެ. އަދި ތިމަންރަސްކަލާނގެ ނަސްރުވެރިކަން އެބޭކަލުންނާ ހަމަޔަށް އަތުވެއްޖައުމަށް ދާންދެން އެބޭކަލުންނަށް ދުއްތުރާ ކުރިއެވެ. އަދި ﷲގެ ކަލިމަފުޅުތަކަށް (އެބަހީ: އެކަލާނގެ ރަސޫލުންނަށް ނަސްރު ދެއްވާނެކަމަށް ކުރައްވާފައިވާ ވައުދުގެ ބަސްފުޅުތަކަށް) ބަދަލެއް ގެންނާނެ އެއްވެސް ފަރާތެއްނެތެވެ. ހަމަކަށަވަރުން، ކުރީގެ ރަސޫލުންގެ ޚަބަރުތައް ކަލޭގެފާނާ ހަމަޔަށް އައިސްފައިވާކަން ކަށަވަރެވެ.","",""],["₆ سورة الأنعام","35","وَإِن كَانَ كَبُرَ عَلَيۡكَ إِعۡرَاضُهُمۡ فَإِنِ ٱسۡتَطَعۡتَ أَن تَبۡتَغِيَ نَفَقٗا فِي ٱلۡأَرۡضِ أَوۡ سُلَّمٗا فِي ٱلسَّمَآءِ فَتَأۡتِيَهُم بِـَٔايَةٖۚ وَلَوۡ شَآءَ ٱللَّهُ لَجَمَعَهُمۡ عَلَى ٱلۡهُدَىٰۚ فَلَا تَكُونَنَّ مِنَ ٱلۡجَٰهِلِينَ ٣٥","وإن كان كبر عليك إعراضهم فإن استطعت أن تبتغي نفقا في الأرض أو سلما في السماء فتأتيهم بآية ولو شاء الله لجمعهم على الهدى فلا تكونن من الجاهلين","އެއުރެން އެނބުރި ފުރަގަސްދިނުން ކަލޭގެފާނަށް ބޮޑުކަމަކަށް ވެއްޖެނަމަ، އެއުރެންނަށް މުއުޖިޒާއެއް ގެނެސް ދެއްވުމަށްޓަކައި ބިމުގެ އަޑީގައި ބިންގަރާހެއް ނުވަތަ އުޑަށް އަރާނެ ސިޑިއެއް ހޯއްދެވުމަށް ކަލޭގެފާނަށް ކުޅަދާނަވެގެންވާނަމަ، އެކަންކުރައްވައި ބައްލަވާށެވެ! (އެބަހީ: ކަލޭގެފާނަކަށް އެކަމެއް ނުކުރެއްވޭނެއެވެ. ކަލޭގެފާނަށް އޮތްކަމަކީ ﷲގެ ހުކުމްފުޅު އަތުވެއްޖައުމަށް ދާނދެން ކެތްކުރެއްވުމެވެ.) ﷲ އިރާދަކުރެއްވިނަމަ، ތެދުމަގުގެ މައްޗަށް އެއުރެން އެއްކުރައްވައިފީހެވެ. ފަހެ، ހަމަކަށަވަރުން، ޖާހިލުންގެ ތެރެއިން ކަލޭގެފާނު ވެވަޑައިނުގަންނަވާށެވެ!","",""],["₆ سورة الأنعام","36","۞إِنَّمَا يَسۡتَجِيبُ ٱلَّذِينَ يَسۡمَعُونَۘ وَٱلۡمَوۡتَىٰ يَبۡعَثُهُمُ ٱللَّهُ ثُمَّ إِلَيۡهِ يُرۡجَعُونَ ٣٦","إنما يستجيب الذين يسمعون والموتى يبعثهم الله ثم إليه يرجعون","ހަމަކަށަވަރުން (ކަލޭގެފާނުންގެ ގޮވައިލެއްވުމަށް) އިޖާބަދެނީ (ވިސްނުމާއެކު) އަޑުއަހާ މީހުންނެވެ. އަދި ﷲ، މަރުވެފައިވާ މީހުން އަލުން ދިރުއްވާހުށްޓެވެ. ދެން އެއުރެން އަނބުރާ ރުޖޫއަކުރައްވާހުށީ އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["₆ سورة الأنعام","37","وَقَالُواْ لَوۡلَا نُزِّلَ عَلَيۡهِ ءَايَةٞ مِّن رَّبِّهِۦۚ قُلۡ إِنَّ ٱللَّهَ قَادِرٌ عَلَىٰٓ أَن يُنَزِّلَ ءَايَةٗ وَلَٰكِنَّ أَكۡثَرَهُمۡ لَا يَعۡلَمُونَ ٣٧","وقالوا لولا نزل عليه آية من ربه قل إن الله قادر على أن ينزل آية ولكن أكثرهم لا يعلمون","އެއުރެން ބުނެފޫއެވެ. އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އެކަލޭގެފާނަށް މުއުޖިޒާއެއް ބާވައިލައްވާފައި ނުވަނީ ކީއްވެގެން ބާވައެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، މުއުޖިޒާއެއް ބާވައިލެއްވުމަށްވެސް ﷲކުޅަދުންވަންތައެވެ. އެހެނެއްކަމަކު އެއުރެންކުރެ ގިނަމީހުން (އެކަމެއް) ނުދަނެތެވެ.","",""],["₆ سورة الأنعام","38","وَمَا مِن دَآبَّةٖ فِي ٱلۡأَرۡضِ وَلَا طَـٰٓئِرٖ يَطِيرُ بِجَنَاحَيۡهِ إِلَّآ أُمَمٌ أَمۡثَالُكُمۚ مَّا فَرَّطۡنَا فِي ٱلۡكِتَٰبِ مِن شَيۡءٖۚ ثُمَّ إِلَىٰ رَبِّهِمۡ يُحۡشَرُونَ ٣٨","وما من دابة في الأرض ولا طائر يطير بجناحيه إلا أمم أمثالكم ما فرطنا في الكتاب من شيء ثم إلى ربهم يحشرون","ބިމުގައި ހިނގާބިނގާއުޅޭ ދިރޭ ކޮންމެ އެއްޗެއްވިޔަސް، އަދި އޭގެ ދެފިޔައިން އުދުހޭ ދޫންޏެއްވިޔަސް، ތިޔަބައިމީހުން ފަދަ އުއްމަތް ތަކެއް ކަމުގައި ނޫނީނުވެއެވެ. ފޮތުގައި (ނުލިޔުއްވާ) ތިމަންރަސްކަލާނގެ އެއްވެސް އެއްޗެއް ދުލެއް ނުކުރައްވަމެވެ. ދެން އެތަކެތި (ގިޔާމަތް ދުވަހުން) އެއްކުރައްވާހުށީ އެތަކެތީގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["₆ سورة الأنعام","39","وَٱلَّذِينَ كَذَّبُواْ بِـَٔايَٰتِنَا صُمّٞ وَبُكۡمٞ فِي ٱلظُّلُمَٰتِۗ مَن يَشَإِ ٱللَّهُ يُضۡلِلۡهُ وَمَن يَشَأۡ يَجۡعَلۡهُ عَلَىٰ صِرَٰطٖ مُّسۡتَقِيمٖ ٣٩","والذين كذبوا بآياتنا صم وبكم في الظلمات من يشإ الله يضلله ومن يشأ يجعله على صراط مستقيم","ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުޅަ މީހުންވަނީ، އަނދިރިތަކެއްގެ ތެރޭގައިވާ، ބީރު އަދި މަންމަން ބަޔަކުކަމުގައެވެ. ﷲ އިރާދަކުރައްވާ މީހަކު މަގު ފުރައްދަވަތެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވާ މީހަކު ސީދާ ވެގެންވާ ތެދުމަގެއްގައި ލަހައްޓަވަތެވެ.","",""],["₆ سورة الأنعام","40","قُلۡ أَرَءَيۡتَكُمۡ إِنۡ أَتَىٰكُمۡ عَذَابُ ٱللَّهِ أَوۡ أَتَتۡكُمُ ٱلسَّاعَةُ أَغَيۡرَ ٱللَّهِ تَدۡعُونَ إِن كُنتُمۡ صَٰدِقِينَ ٤٠","قل أرأيتكم إن أتاكم عذاب الله أو أتتكم الساعة أغير الله تدعون إن كنتم صادقين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންނީ، ތެދުބުނާ މީހުން ކަމުގައިވާނަމަ، ނިކަން ތިޔަބައިމީހުން ބުނެބަލާށެވެ! ތިޔަބައިމީހުންގެ ގާތަށް ﷲގެ އަޒާބު އަތުވެއްޖެނަމަ، ނުވަތަ ގިޔާމަތްގެ ވަގުތު ތިޔަބައިމީހުންގެ ގާތަށް އަތުވެއްޖެނަމަ، ﷲ ނޫންފަރާތަކަށް ތިޔަބައިމީހުން ދުއާކުރާނެހެއްޔެވެ؟","",""],["₆ سورة الأنعام","41","بَلۡ إِيَّاهُ تَدۡعُونَ فَيَكۡشِفُ مَا تَدۡعُونَ إِلَيۡهِ إِن شَآءَ وَتَنسَوۡنَ مَا تُشۡرِكُونَ ٤١","بل إياه تدعون فيكشف ما تدعون إليه إن شاء وتنسون ما تشركون","އަދި ކިއެއްތަ! ތިޔަބައިމީހުން ދުއާކުރާނީ ހަމައެކަނި އެކަލާނގެއަށެވެ. ދެން ތިޔަބައިމީހުން ދުއާ ކޮށް (ފިއްލެވުންއެދި) ދެންނެވިކަމެއް އެކަލާނގެ އިރާދަކުރައްވައިފިނަމަ، ފިއްލަވާނެތެވެ. އަދި ތިޔަބައިމީހުން ޝަރީކުކުޅަ ފަރާތްތައް ތިޔަބައިމީހުން ހަނދާން ނައްތައިލާނޫއެވެ.","",""],["₆ سورة الأنعام","42","وَلَقَدۡ أَرۡسَلۡنَآ إِلَىٰٓ أُمَمٖ مِّن قَبۡلِكَ فَأَخَذۡنَٰهُم بِٱلۡبَأۡسَآءِ وَٱلضَّرَّآءِ لَعَلَّهُمۡ يَتَضَرَّعُونَ ٤٢","ولقد أرسلنا إلى أمم من قبلك فأخذناهم بالبأساء والضراء لعلهم يتضرعون","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ކުރީގެ އުއްމަތް ތަކަށްވެސް ތިމަންރަސްކަލާނގެ ރަސޫލުން ފޮނުއްވީމެވެ. ދެން (އެއުރެން ކާފިރު ވީހިނދު) ތަދުމަޑުކަމާއި ބަލިމަޑުކަން، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ޖެއްސެވީމެވެ. (އެއީ) އެއުރެން ކިޔަމަންވެ މަޑުމޮޅިވުމަށްޓަކައެވެ.","",""],["₆ سورة الأنعام","43","فَلَوۡلَآ إِذۡ جَآءَهُم بَأۡسُنَا تَضَرَّعُواْ وَلَٰكِن قَسَتۡ قُلُوبُهُمۡ وَزَيَّنَ لَهُمُ ٱلشَّيۡطَٰنُ مَا كَانُواْ يَعۡمَلُونَ ٤٣","فلولا إذ جاءهم بأسنا تضرعوا ولكن قست قلوبهم وزين لهم الشيطان ما كانوا يعملون","ފަހެ، ތިމަންރަސްކަލާނގެ އަޒާބެއުރެންނާ ހަމަޔަށް އައިހިނދުވެސް، އެއުރެން ކިޔަމަންވެ މަޑުމޮޅިނުވީ ކީއްވެގެންބާވައެވެ؟ އެހެނެއްކަމަކު އެއުރެންގެ ހިތްތައް ހަރުކަށިވެފައިވެއެވެ. އަދި އެއުރެން ކޮށްއުޅުނު ކަންތައް އެއުރެންނަށް ޝައިތާނާ ޒީނަތްތެރިކޮށް ދެއްކިއެވެ.","",""],["₆ سورة الأنعام","44","فَلَمَّا نَسُواْ مَا ذُكِّرُواْ بِهِۦ فَتَحۡنَا عَلَيۡهِمۡ أَبۡوَٰبَ كُلِّ شَيۡءٍ حَتَّىٰٓ إِذَا فَرِحُواْ بِمَآ أُوتُوٓاْ أَخَذۡنَٰهُم بَغۡتَةٗ فَإِذَا هُم مُّبۡلِسُونَ ٤٤","فلما نسوا ما ذكروا به فتحنا عليهم أبواب كل شيء حتى إذا فرحوا بما أوتوا أخذناهم بغتة فإذا هم مبلسون","ދެން އެއުރެންނަށް ހަނދާންކޮށްދެއްވި ކަންތައް، އެއުރެން ހަނދާންނައްތައިފި ހިނދު (އިމްތިހާނެއްގެ ގޮތުން) ހުރިހާކަމެއްގެ ދޮރުތައް ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ހުޅުއްވައިދެއްވީމެވެ. (އެބަހީ: ހުރިހާ ގޮތަކުން ތަނަވަސްކަމާއި ތިޔާގިކަން ދެއްވީމެވެ.) ދެން އެއުރެންނަށް ދެއްވި ކަންތަކާމެދު އެއުރެން އުފަލުގައި ތިއްބާ ކުއްލިއަކަށް ތިމަންރަސްކަލާނގެ އެއުރެން ހިއްޕެވީމެވެ. އެހިނދު އުއްމީދު ކެނޑިފައިތިބި ބަޔަކު ކަމުގައި އެއުރެންވިއެވެ.","",""],["₆ سورة الأنعام","45","فَقُطِعَ دَابِرُ ٱلۡقَوۡمِ ٱلَّذِينَ ظَلَمُواْۚ وَٱلۡحَمۡدُ لِلَّهِ رَبِّ ٱلۡعَٰلَمِينَ ٤٥","فقطع دابر القوم الذين ظلموا والحمد لله رب العالمين","ދެން އަނިޔާވެރިވީ މީހުންގެ އެންމެފަހު މީހާއަށްދާނދެން ނެތި ކުރެއްވިއެވެ. ހަމްދު ހުރީ، އާލަމްތަކުގެ ވެރި ﷲއަށެވެ.","",""],["₆ سورة الأنعام","46","قُلۡ أَرَءَيۡتُمۡ إِنۡ أَخَذَ ٱللَّهُ سَمۡعَكُمۡ وَأَبۡصَٰرَكُمۡ وَخَتَمَ عَلَىٰ قُلُوبِكُم مَّنۡ إِلَٰهٌ غَيۡرُ ٱللَّهِ يَأۡتِيكُم بِهِۗ ٱنظُرۡ كَيۡفَ نُصَرِّفُ ٱلۡأٓيَٰتِ ثُمَّ هُمۡ يَصۡدِفُونَ ٤٦","قل أرأيتم إن أخذ الله سمعكم وأبصاركم وختم على قلوبكم من إله غير الله يأتيكم به انظر كيف نصرف الآيات ثم هم يصدفون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ނިކަން ބުނެބަލާށެވެ! ﷲ ތިޔަބައިމީހުންގެ އިވުމާއި، ފެނުން ގެންދަވައި އަދި ތިޔަބައިމީހުންގެ ހިތްތަކުގައި ސިއްކަގައްސަވައިފިނަމަ، އެކަންތައްތައް ތިޔަބައިމީހުންނަށް އަލުން ގެނެސްދޭނީ ﷲ ފިޔަވައި ކޮން އިލާހަކު ހެއްޔެވެ؟ ތިމަންރަސްކަލާނގެ އާޔަތްތައް އެކިގޮތްގޮތަށް ބަޔާންކޮށްދެއްވަނީ، ކޮންފަދައަކުންކަން ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާށެވެ! ދެން އެއަށްފަހުވެސް، އެއުރެން އެ އާޔަތް ތަކުން ދުރުހެލިވެގަނެތެވެ.","",""],["₆ سورة الأنعام","47","قُلۡ أَرَءَيۡتَكُمۡ إِنۡ أَتَىٰكُمۡ عَذَابُ ٱللَّهِ بَغۡتَةً أَوۡ جَهۡرَةً هَلۡ يُهۡلَكُ إِلَّا ٱلۡقَوۡمُ ٱلظَّـٰلِمُونَ ٤٧","قل أرأيتكم إن أتاكم عذاب الله بغتة أو جهرة هل يهلك إلا القوم الظالمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ނިކަން ބުނެބަލާށެވެ! ﷲގެ އަޒާބު ކުއްލިއަކަށް ނުވަތަ ފާޅުގައި ތިޔަބައިމީހުންގެ ގާތަށް އަތުވެއްޖެނަމަ، އަނިޔާވެރިވީ މީހުން ފިޔަވައި އެހެން ބަޔަކު ހަލާކުވެގެންދާނޭ ހެއްޔެވެ؟","",""],["₆ سورة الأنعام","48","وَمَا نُرۡسِلُ ٱلۡمُرۡسَلِينَ إِلَّا مُبَشِّرِينَ وَمُنذِرِينَۖ فَمَنۡ ءَامَنَ وَأَصۡلَحَ فَلَا خَوۡفٌ عَلَيۡهِمۡ وَلَا هُمۡ يَحۡزَنُونَ ٤٨","وما نرسل المرسلين إلا مبشرين ومنذرين فمن آمن وأصلح فلا خوف عليهم ولا هم يحزنون","އަދި އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާ، ބޭކަލުން ކަމުގައްޔާއި، އިންޒާރުކުރައްވާ ބޭކަލުން ކަމުގައިމެނުވީ، ތިމަންރަސްކަލާނގެ ރަސޫލުން ނުފޮނުއްވަމެވެ. ފަހެ، އީމާންވެ އިސްލާހުކުޅަ މީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެންގެ މައްޗަކަށް އެއްވެސް ބިރެއް ނެތެވެ. އަދި އެއުރެންނަކީ ހިތާމަކުރާނޭ ބަޔަކު ކަމުގައިވެސް ނުމެވޭމެއެވެ.","",""],["₆ سورة الأنعام","49","وَٱلَّذِينَ كَذَّبُواْ بِـَٔايَٰتِنَا يَمَسُّهُمُ ٱلۡعَذَابُ بِمَا كَانُواْ يَفۡسُقُونَ ٤٩","والذين كذبوا بآياتنا يمسهم العذاب بما كانوا يفسقون","ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުޅަ މީހުން (ދަންނާށެވެ!) އެއުރެން ފާސިގުވެ އުޅުނު ކަމަށްޓަކައި އަޒާބެއުރެންގައި ބީހޭނެތެވެ.","",""],["₆ سورة الأنعام","50","قُل لَّآ أَقُولُ لَكُمۡ عِندِي خَزَآئِنُ ٱللَّهِ وَلَآ أَعۡلَمُ ٱلۡغَيۡبَ وَلَآ أَقُولُ لَكُمۡ إِنِّي مَلَكٌۖ إِنۡ أَتَّبِعُ إِلَّا مَا يُوحَىٰٓ إِلَيَّۚ قُلۡ هَلۡ يَسۡتَوِي ٱلۡأَعۡمَىٰ وَٱلۡبَصِيرُۚ أَفَلَا تَتَفَكَّرُونَ ٥٠","قل لا أقول لكم عندي خزائن الله ولا أعلم الغيب ولا أقول لكم إني ملك إن أتبع إلا ما يوحى إلي قل هل يستوي الأعمى والبصير أفلا تتفكرون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނުގެ ގާތުގައި ﷲގެ ޚަޒާނާތައް ވާކަމަކަށް، ނުވަތަ ތިމަންކަލޭގެފާނަށް ޣައިބު އެނގޭކަމަކަށް ތިޔަބައިމީހުންގެ ގާތަކު ތިމަންކަލޭގެފާނު ވިދާޅެއް ނުވަމެވެ. އަދި ތިމަންކަލޭގެފާނީ މަލާއިކަތް އެކޭވެސް ތިޔަބައިމީހުންގެ ގާތަކު ވިދާޅެއްނުވަމެވެ. ތިމަންކަލޭގެފާނަށް ވަހީ އިއްވަވާގޮތަށް މެނުވީ ތިމަންކަލޭގެފާނު ތަބާ ވެވަޑައެއް ނުގަންނަވަމެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ކަނުމީހަކާ، ލޮލަށްފެންނަ މީހަކާ ހަމަހަމަވާނޭހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުން ފިކުރު ނުކުރަނީހެއްޔެވެ؟","",""],["₆ سورة الأنعام","51","وَأَنذِرۡ بِهِ ٱلَّذِينَ يَخَافُونَ أَن يُحۡشَرُوٓاْ إِلَىٰ رَبِّهِمۡ لَيۡسَ لَهُم مِّن دُونِهِۦ وَلِيّٞ وَلَا شَفِيعٞ لَّعَلَّهُمۡ يَتَّقُونَ ٥١","وأنذر به الذين يخافون أن يحشروا إلى ربهم ليس لهم من دونه ولي ولا شفيع لعلهم يتقون","އަދި އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް އެއުރެން އެއްކުރައްވާނޭ ކަމާމެދު ބިރުވެތިވެއުޅޭ މީހުންނަށް އެ ގުރްއާނުން ކަލޭގެފާނު އިންޒާރުކުރައްވާށެވެ! އެކަލާނގެ ފިޔަވައި އެހީތެރިޔަކުވެސް، ޝަފާއަތް ތެރިޔަކުވެސް އެއުރެންނަކަށް ނުވެއެވެ. (އެއީ) އެއުރެން ތަގުވާވެރި ވުމަށްޓަކައެވެ.","",""],["₆ سورة الأنعام","52","وَلَا تَطۡرُدِ ٱلَّذِينَ يَدۡعُونَ رَبَّهُم بِٱلۡغَدَوٰةِ وَٱلۡعَشِيِّ يُرِيدُونَ وَجۡهَهُۥۖ مَا عَلَيۡكَ مِنۡ حِسَابِهِم مِّن شَيۡءٖ وَمَا مِنۡ حِسَابِكَ عَلَيۡهِم مِّن شَيۡءٖ فَتَطۡرُدَهُمۡ فَتَكُونَ مِنَ ٱلظَّـٰلِمِينَ ٥٢","ولا تطرد الذين يدعون ربهم بالغداة والعشي يريدون وجهه ما عليك من حسابهم من شيء وما من حسابك عليهم من شيء فتطردهم فتكون من الظالمين","އަދި އެއުރެން އެކަލާނގެ ވަޖުހުފުޅު އެދިގެން ހެނދުނާއި، ހަވީރު އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ދުއާ ކޮށްއުޅޭ މީހުން ކަލޭގެފާނު ދުރުކޮށް ނުލައްވާށެވެ! އެއުރެންގެ ހިސާބު ބެއްލެވުމުގެ ތެރެއިން ކަމެއް ކަލޭގެފާނަކަށް ނެތެވެ. އަދި ކަލޭގެފާނުގެ ހިސާބު ބެއްލެވުމުގެ ތެރެއިން ކަމެއް އެއުރެންނަކަށްވެސް ނެތެވެ. ފަހެ، ކަލޭގެފާނު އެއުރެން ދުރުކޮށްލައްވައިފިނަމަ، އަނިޔާވެރިންގެ ތެރެއިން ކަލޭގެފާނު ވެދާނެތެވެ.","",""],["₆ سورة الأنعام","53","وَكَذَٰلِكَ فَتَنَّا بَعۡضَهُم بِبَعۡضٖ لِّيَقُولُوٓاْ أَهَـٰٓؤُلَآءِ مَنَّ ٱللَّهُ عَلَيۡهِم مِّنۢ بَيۡنِنَآۗ أَلَيۡسَ ٱللَّهُ بِأَعۡلَمَ بِٱلشَّـٰكِرِينَ ٥٣","وكذلك فتنا بعضهم ببعض ليقولوا أهؤلاء من الله عليهم من بيننا أليس الله بأعلم بالشاكرين","އެއުރެންގެ އެއްބަޔަކު އަނެއްބަޔަކު މެދުވެރި ކުރައްވައި އިމްތިހާނުކުރައްވަމުން ތިމަންރަސްކަލާނގެ ގެންދެވީ އެފަދައިންނެވެ. އެއީ އަހުރެމެންގެ ތެރެއިން ﷲ ނިއުމަތް ދެއްވާފައިވާ ބަޔަކީ މިބައިމީހުންހޭ؟ އެއުރެން ބުނުމަށްޓަކައެވެ. ޝުކުރުވެރިވާ މީހުން އެންމެބޮޑަށް ދެނެވޮޑިގެންވަނީ، ﷲކަމުގައިނުވޭ ހެއްޔެވެ؟","",""],["₆ سورة الأنعام","54","وَإِذَا جَآءَكَ ٱلَّذِينَ يُؤۡمِنُونَ بِـَٔايَٰتِنَا فَقُلۡ سَلَٰمٌ عَلَيۡكُمۡۖ كَتَبَ رَبُّكُمۡ عَلَىٰ نَفۡسِهِ ٱلرَّحۡمَةَ أَنَّهُۥ مَنۡ عَمِلَ مِنكُمۡ سُوٓءَۢا بِجَهَٰلَةٖ ثُمَّ تَابَ مِنۢ بَعۡدِهِۦ وَأَصۡلَحَ فَأَنَّهُۥ غَفُورٞ رَّحِيمٞ ٥٤","وإذا جاءك الذين يؤمنون بآياتنا فقل سلام عليكم كتب ربكم على نفسه الرحمة أنه من عمل منكم سوءا بجهالة ثم تاب من بعده وأصلح فأنه غفور رحيم","ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް އީމާންވާ މީހުން ކަލޭގެފާނުގެ އަރިހަށް އަތުވެއްޖެނަމަ، ފަހެ، ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންގެ މައްޗަށް ސަލާމް ހުށްޓެވެ. ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ރަހުމަތް އެކަލާނގެ ޛާތު ފުޅުގެ މައްޗަށް ލާޒިމްކުރެއްވިއެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ތެރެއިން ނޭނގުމާއެކު، ނުބައިކަމެއްކޮށް، ދެން އެއަށްފަހު، ތައުބާވެ (ޢަމަލުތައް) އިސްލާހު ކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އެކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","55","وَكَذَٰلِكَ نُفَصِّلُ ٱلۡأٓيَٰتِ وَلِتَسۡتَبِينَ سَبِيلُ ٱلۡمُجۡرِمِينَ ٥٥","وكذلك نفصل الآيات ولتستبين سبيل المجرمين","ތިމަންރަސްކަލާނގެ އާޔަތްތައް ބަޔާންކުރައްވަނީ އެފަދައިންނެވެ. އެއީ ކުށްވެރިންގެ މަގު ބަޔާންވެ އޮތުމަށްޓަކައެވެ.","",""],["₆ سورة الأنعام","56","قُلۡ إِنِّي نُهِيتُ أَنۡ أَعۡبُدَ ٱلَّذِينَ تَدۡعُونَ مِن دُونِ ٱللَّهِۚ قُل لَّآ أَتَّبِعُ أَهۡوَآءَكُمۡ قَدۡ ضَلَلۡتُ إِذٗا وَمَآ أَنَا۠ مِنَ ٱلۡمُهۡتَدِينَ ٥٦","قل إني نهيت أن أعبد الذين تدعون من دون الله قل لا أتبع أهواءكم قد ضللت إذا وما أنا من المهتدين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲ ފިޔަވައި ތިޔަބައިމީހުން ދުއާ ކޮށްއުޅޭ ފަރާތްތަކަށް އަޅުކަންކުރުން ތިމަންކަލޭގެފާނަށް ހަމަކަށަވަރުން، ނަހީކުރެއްވިއެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންގެ އެދުންތަކަކަށް ތިމަންކަލޭގެފާނު ތަބައެއް ނުވާނަމެވެ. އެހެންވެއްޖެނަމަ، ތިމަންކަލޭގެފާނު މަގުފުރެދުނީސްކަން ކަށަވަރެވެ. އަދި އޭރުން ތެދުމަގު ލިބިގެންވާ މީހުންގެ ތެރެއިން ތިމަންކަލޭގެފާނު ނުވީހެވެ.","",""],["₆ سورة الأنعام","57","قُلۡ إِنِّي عَلَىٰ بَيِّنَةٖ مِّن رَّبِّي وَكَذَّبۡتُم بِهِۦۚ مَا عِندِي مَا تَسۡتَعۡجِلُونَ بِهِۦٓۚ إِنِ ٱلۡحُكۡمُ إِلَّا لِلَّهِۖ يَقُصُّ ٱلۡحَقَّۖ وَهُوَ خَيۡرُ ٱلۡفَٰصِلِينَ ٥٧","قل إني على بينة من ربي وكذبتم به ما عندي ما تستعجلون به إن الحكم إلا لله يقص الحق وهو خير الفاصلين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނު ވަނީ ތިމަންކަލޭގެފާނުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ބަޔާންވެ އެނގިގެންވާ ކަންތައްތަކެއްގެ މަތީގައެވެ. އަދި ތިޔަބައިމީހުން އެކަލާނގެ ދޮގުކުޅައީމުއެވެ. އެކަމެއް އަވަސްވުންއެދި ތިޔަބައިމީހުން އުޅޭކަންތައް (އެބަހީ: ﷲގެ އަޒާބު ފޮނުއްވުން) ތިމަންކަލޭގެފާނުންގެ ކިބަޔަކު ނުވެއެވެ. ހުކުމްކުރެއްވުން ﷲއަށް މެނުވީ ނުވެއެވެ. އެކަލާނގެ ހައްގު ބަސްފުޅު ވަހީކުރައްވައެވެ. އެކަލާނގެއީ، ހުކުމްކުރައްވާ އެންމެ ހެޔޮ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","58","قُل لَّوۡ أَنَّ عِندِي مَا تَسۡتَعۡجِلُونَ بِهِۦ لَقُضِيَ ٱلۡأَمۡرُ بَيۡنِي وَبَيۡنَكُمۡۗ وَٱللَّهُ أَعۡلَمُ بِٱلظَّـٰلِمِينَ ٥٨","قل لو أن عندي ما تستعجلون به لقضي الأمر بيني وبينكم والله أعلم بالظالمين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަމެއް އަވަސްވުންއެދި، ތިޔަބައިމީހުން އުޅޭކަންތައް ތިމަންކަލޭގެފާނުގެ ކިބައިގައިވާނަމަ، ތިމަންކަލޭގެފާނާ ތިޔަބައިމީހުންނާ ދެމެދުގައިވާ ކަންތަކުގެ ނިޔާކަނޑައަޅުއްވައި ނިންމަވައިފީސްކަން ކަށަވަރެވެ. އަނިޔާވެރިން ދެނެވޮޑިގަތުންބޮޑީ، ﷲއެވެ.","",""],["₆ سورة الأنعام","59","۞وَعِندَهُۥ مَفَاتِحُ ٱلۡغَيۡبِ لَا يَعۡلَمُهَآ إِلَّا هُوَۚ وَيَعۡلَمُ مَا فِي ٱلۡبَرِّ وَٱلۡبَحۡرِۚ وَمَا تَسۡقُطُ مِن وَرَقَةٍ إِلَّا يَعۡلَمُهَا وَلَا حَبَّةٖ فِي ظُلُمَٰتِ ٱلۡأَرۡضِ وَلَا رَطۡبٖ وَلَا يَابِسٍ إِلَّا فِي كِتَٰبٖ مُّبِينٖ ٥٩","وعنده مفاتح الغيب لا يعلمها إلا هو ويعلم ما في البر والبحر وما تسقط من ورقة إلا يعلمها ولا حبة في ظلمات الأرض ولا رطب ولا يابس إلا في كتاب مبين","އަދި ޣައިބުގެ ތަޅުދަނޑިތައްވަނީ، އެކަލާނގެ ހަޒުރަތު ގައެވެ. އެކަލާނގެ މެނުވީ، އެކަންތައްތައް ދެނެވޮޑިގެންނުވެތެވެ. އެއްގަމާއި، ކަނޑުގައިވާ ކަންތައްތައް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އެކަލާނގެ ދެނެވޮޑިގެން މެނުވީ ގަހެއްގެ ފަތެއްވެސް ނުވެއްޓެއެވެ. އަދި ބިމުގެ އަނދިރިކަމުގެ ތެރޭގައިވާ އޮށްޓަރެއްވިޔަސް، އަދި ރޯއެއްޗެއްވިޔަސް، ހިކިއެއްޗެއްވިޔަސް، ބަޔާންވެގެންވާ ފޮތެއްގައި (ލިޔުއްވާފައި) މެނުވީ ނުވެތެވެ.","",""],["₆ سورة الأنعام","60","وَهُوَ ٱلَّذِي يَتَوَفَّىٰكُم بِٱلَّيۡلِ وَيَعۡلَمُ مَا جَرَحۡتُم بِٱلنَّهَارِ ثُمَّ يَبۡعَثُكُمۡ فِيهِ لِيُقۡضَىٰٓ أَجَلٞ مُّسَمّٗىۖ ثُمَّ إِلَيۡهِ مَرۡجِعُكُمۡ ثُمَّ يُنَبِّئُكُم بِمَا كُنتُمۡ تَعۡمَلُونَ ٦٠","وهو الذي يتوفاكم بالليل ويعلم ما جرحتم بالنهار ثم يبعثكم فيه ليقضى أجل مسمى ثم إليه مرجعكم ثم ينبئكم بما كنتم تعملون","އަދި ރޭގަނޑަށް ތިޔަބައިމީހުންގެ ފުރާނަ ހިއްޕަވަނީ (އެބަހީ: ނިދޭގޮތް މެދުވެރި ކުރައްވަނީ) އެކަލާނގެއެވެ. އަދި ދުވާލު ތިޔަބައިމީހުން ހޯދައިގަތް ކަމެއް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. ދެން އެއަށްފަހު ދުވާލުގެ ތެރެއަށް ތިޔަބައިމީހުން އަލުން ފޮނުއްވަތެވެ. (އެބަހީ: ހޭލައްވަވައެވެ. އެއީ) ކަނޑައަޅުއްވާފައިވާއަޖަލު ހަމަވުމަށްޓަކައެވެ. ދެން އެއަށްފަހު، ތިޔަބައިމީހުން އެނބުރި ރުޖޫއަ ވުންވަނީ، އެކަލާނގެ ހަޒުރަތަށެވެ. ދެން އެއަށްފަހު، ތިޔަބައިމީހުން ކޮށްއުޅުނު ކަންތަކުގެ ޚަބަރު، ތިޔަބައިމީހުންނަށް އެކަލާނގެ އަންގަވާނެތެވެ.","",""],["₆ سورة الأنعام","61","وَهُوَ ٱلۡقَاهِرُ فَوۡقَ عِبَادِهِۦۖ وَيُرۡسِلُ عَلَيۡكُمۡ حَفَظَةً حَتَّىٰٓ إِذَا جَآءَ أَحَدَكُمُ ٱلۡمَوۡتُ تَوَفَّتۡهُ رُسُلُنَا وَهُمۡ لَا يُفَرِّطُونَ ٦١","وهو القاهر فوق عباده ويرسل عليكم حفظة حتى إذا جاء أحدكم الموت توفته رسلنا وهم لا يفرطون","އަދި އެކަލާނގެއީ، އެކަލާނގެ އަޅުތަކުންގެ މައްޗަށް ގަދަވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އެކަލާނގެ ތިޔަބައިމީހުންގެ މައްޗަށް ރައްކާތެރިކުރަނިވި މަލާއިކަތުން ފޮނުއްވަވަތެވެ. ތިޔަބައިމީހުންގެ ތެރެއިން މީހަކުގެ ގާތަށް މަރު އަތުވެއްޖެނަމަ، އެހިނދު ތިމަންރަސްކަލާނގެ ފޮނުއްވަވާ މަލާއިކަތުން އެމީހަކުގެ ފުރާނަ ހިއްޕަވަތެވެ. އެ މަލާއިކަތުން (އެކަމުގައި) ލަހެއް ފަހެއް ނުކުރައްވާނެތެވެ.","",""],["₆ سورة الأنعام","62","ثُمَّ رُدُّوٓاْ إِلَى ٱللَّهِ مَوۡلَىٰهُمُ ٱلۡحَقِّۚ أَلَا لَهُ ٱلۡحُكۡمُ وَهُوَ أَسۡرَعُ ٱلۡحَٰسِبِينَ ٦٢","ثم ردوا إلى الله مولاهم الحق ألا له الحكم وهو أسرع الحاسبين","ދެން އެއުރެންގެ އެހީތެރިވަންތަ، ހައްގުވަންތަ ﷲގެ ހަޒުރަތަށް އެއުރެން ރައްދުކުރައްވާނެތެވެ. ދަންނާށެވެ! ހުކުމްކުރެއްވުންއޮތީ، އެކަލާނގެއަށެވެ. އެކަލާނގެއީ، ހިސާބު ބެއްލެވުމުގައި އެންމެ އަވަސް ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","63","قُلۡ مَن يُنَجِّيكُم مِّن ظُلُمَٰتِ ٱلۡبَرِّ وَٱلۡبَحۡرِ تَدۡعُونَهُۥ تَضَرُّعٗا وَخُفۡيَةٗ لَّئِنۡ أَنجَىٰنَا مِنۡ هَٰذِهِۦ لَنَكُونَنَّ مِنَ ٱلشَّـٰكِرِينَ ٦٣","قل من ينجيكم من ظلمات البر والبحر تدعونه تضرعا وخفية لئن أنجانا من هذه لنكونن من الشاكرين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއްގަމާއި، ކަނޑުގެ އަނދިރިތަކުގެ ތެރެއިން (އެބަހީ: އެއްގަމާއި، ކަނޑުގެ ބިރުވެރިކަމުގެ ތެރެއިން) ތިޔަބައިމީހުން މިންޖުކުރާނީ ކާކުހެއްޔެވެ؟ މަޑުމޮޅިކަމާއި، ވަންހަނާ ގޮތުގައި، ތިޔަބައިމީހުން އެކަލާނގެއަށް ދުއާ ކޮށް ދަންނަވަމުއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެ ތިމަންމެން މިކަމުން ސަލާމަތް ކުރައްވައިފިނަމަ، ޝުކުރުވެރިވާ މީހުންގެ ތެރެއިން ހަމަކަށަވަރުން ތިމަންމެން ވާހުށީމެވެ.","",""],["₆ سورة الأنعام","64","قُلِ ٱللَّهُ يُنَجِّيكُم مِّنۡهَا وَمِن كُلِّ كَرۡبٖ ثُمَّ أَنتُمۡ تُشۡرِكُونَ ٦٤","قل الله ينجيكم منها ومن كل كرب ثم أنتم تشركون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަމުންވެސް އަދި ކޮންމެ ހިތާމައަކުންވެސް ތިޔަބައިމީހުން ސަލާމަތްކުރައްވާނީ ﷲއެވެ. ދެން އެއަށްފަހުވެސް، ތިޔަބައިމީހުން ޝަރީކުކުރަމުއެވެ.","",""],["₆ سورة الأنعام","65","قُلۡ هُوَ ٱلۡقَادِرُ عَلَىٰٓ أَن يَبۡعَثَ عَلَيۡكُمۡ عَذَابٗا مِّن فَوۡقِكُمۡ أَوۡ مِن تَحۡتِ أَرۡجُلِكُمۡ أَوۡ يَلۡبِسَكُمۡ شِيَعٗا وَيُذِيقَ بَعۡضَكُم بَأۡسَ بَعۡضٍۗ ٱنظُرۡ كَيۡفَ نُصَرِّفُ ٱلۡأٓيَٰتِ لَعَلَّهُمۡ يَفۡقَهُونَ ٦٥","قل هو القادر على أن يبعث عليكم عذابا من فوقكم أو من تحت أرجلكم أو يلبسكم شيعا ويذيق بعضكم بأس بعض انظر كيف نصرف الآيات لعلهم يفقهون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަލާނގެއީ، ތިޔަބައިމީހުންގެ (ބޯ) މަތިން ނުވަތަ ތިޔަބައިމީހުންގެ ފައިތަކުގެ ދަށުން، ތިޔަބައިމީހުންގެ މައްޗަށް އަޒާބެއް ފޮނުއްވުމަށް ނުވަތަ ތިޔަބައިމީހުން ބައިބަޔަށް ވަކިކުރައްވައި ތިޔަބައިމީހުންގެ ތެރެއިން އެއްބަޔެއްގެ ބާރުގެ ރަހަ، އަނެއްބަޔަކަށް ދެއްކެވުމަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ. ތިމަންރަސްކަލާނގެ އާޔަތްތައް އެކިގޮތްގޮތަށް ބަޔާންކޮށް ދެއްވަނީ، ކޮންފަދަޔަކުންކަން ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާށެވެ! (އެއީ) އެއުރެން ވިސްނުމަށްޓަކައެވެ.","",""],["₆ سورة الأنعام","66","وَكَذَّبَ بِهِۦ قَوۡمُكَ وَهُوَ ٱلۡحَقُّۚ قُل لَّسۡتُ عَلَيۡكُم بِوَكِيلٖ ٦٦","وكذب به قومك وهو الحق قل لست عليكم بوكيل","އެއީ ހައްގު ތެދުބަސްފުޅުކަމަށް ވުމާއެކުވެސް، ކަލޭގެފާނުގެ ގައުމުގެމީހުން އެ ގުރްއާން ދޮގުކުޅައޫއެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންގެ ކަންތަކާ ޙަވާލު ވެގެންހުރި ވަކީލަކު ކަމުގައި ތިމަންކަލޭގެފާނު ނުވަމެވެ.","",""],["₆ سورة الأنعام","67","لِّكُلِّ نَبَإٖ مُّسۡتَقَرّٞۚ وَسَوۡفَ تَعۡلَمُونَ ٦٧","لكل نبإ مستقر وسوف تعلمون","ކޮންމެ ޚަބަރަކަށްމެ، ކަނޑައަޅުއްވާފައިވާ ވަގުތެއްވެއެވެ. އަދި ނިކަންހުރެ ތިޔަބައިމީހުންނަށް އެނގޭނެތެވެ.","",""],["₆ سورة الأنعام","68","وَإِذَا رَأَيۡتَ ٱلَّذِينَ يَخُوضُونَ فِيٓ ءَايَٰتِنَا فَأَعۡرِضۡ عَنۡهُمۡ حَتَّىٰ يَخُوضُواْ فِي حَدِيثٍ غَيۡرِهِۦۚ وَإِمَّا يُنسِيَنَّكَ ٱلشَّيۡطَٰنُ فَلَا تَقۡعُدۡ بَعۡدَ ٱلذِّكۡرَىٰ مَعَ ٱلۡقَوۡمِ ٱلظَّـٰلِمِينَ ٦٨","وإذا رأيت الذين يخوضون في آياتنا فأعرض عنهم حتى يخوضوا في حديث غيره وإما ينسينك الشيطان فلا تقعد بعد الذكرى مع القوم الظالمين","ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާމެދު ދޮގުވާހަކަ ދައްކައިއުޅޭ މީހުން ކަލޭގެފާނަށް ފެނިވަޑައިގެންފިނަމަ، އެއުރެން އެ ނޫން ވާހަކައެއް ދައްކައިފުމަށް ދާނދެން އެއުރެންގެ ކިބައިން ވަކިވެވަޑައިގަންނަވާށެވެ! އަދި ޝައިތާނާ ކަލޭގެފާނު ހަނދުމަނެތި ކޮށްފިނަމަ (އެކަން) ހަނދުމަވުމަށްފަހު، އަނިޔާވެރިވީ މީސްތަކުންނާއެކު ފަހެ، ކަލޭގެފާނު ނީންނަވާށެވެ!","",""],["₆ سورة الأنعام","69","وَمَا عَلَى ٱلَّذِينَ يَتَّقُونَ مِنۡ حِسَابِهِم مِّن شَيۡءٖ وَلَٰكِن ذِكۡرَىٰ لَعَلَّهُمۡ يَتَّقُونَ ٦٩","وما على الذين يتقون من حسابهم من شيء ولكن ذكرى لعلهم يتقون","އަދި އެ (ދޮގުވާހަކަ ދައްކާ) މީހުންގެ އެއްވެސް ކަމެއްގެ ޒިންމާއެއް، ތަގުވާވެރިންގެ މައްޗަކަށް ނެތެވެ. އެހެނެއްކަމަކު، އޮތްކަމަކީ ހަނދާންކޮށްދިނުމެވެ. އެއީ އެއުރެން (އެފަދަ ވާހަކަތަކުން) ރައްކާތެރިވުމަށްޓަކައެވެ.","",""],["₆ سورة الأنعام","70","وَذَرِ ٱلَّذِينَ ٱتَّخَذُواْ دِينَهُمۡ لَعِبٗا وَلَهۡوٗا وَغَرَّتۡهُمُ ٱلۡحَيَوٰةُ ٱلدُّنۡيَاۚ وَذَكِّرۡ بِهِۦٓ أَن تُبۡسَلَ نَفۡسُۢ بِمَا كَسَبَتۡ لَيۡسَ لَهَا مِن دُونِ ٱللَّهِ وَلِيّٞ وَلَا شَفِيعٞ وَإِن تَعۡدِلۡ كُلَّ عَدۡلٖ لَّا يُؤۡخَذۡ مِنۡهَآۗ أُوْلَـٰٓئِكَ ٱلَّذِينَ أُبۡسِلُواْ بِمَا كَسَبُواْۖ لَهُمۡ شَرَابٞ مِّنۡ حَمِيمٖ وَعَذَابٌ أَلِيمُۢ بِمَا كَانُواْ يَكۡفُرُونَ ٧٠","وذر الذين اتخذوا دينهم لعبا ولهوا وغرتهم الحياة الدنيا وذكر به أن تبسل نفس بما كسبت ليس لها من دون الله ولي ولا شفيع وإن تعدل كل عدل لا يؤخذ منها أولئك الذين أبسلوا بما كسبوا لهم شراب من حميم وعذاب أليم بما كانوا يكفرون","އެއުރެންގެ ދީނުގެ ކަންތަކަކީ، ކުޅިވަރެއް ކަމުގައްޔާއި، ފޫހިފިލުވުމެއް ކަމުގައި ބަލައިގެން އުޅުނު، އަދި ދުނިޔޭގެ ދިރިއުޅުން އެއުރެން ހެއްލުންތެރިކޮށްފައިވާ މީހުން ކަލޭގެފާނު ދޫކޮށްލައްވާށެވެ! އަދި ކަލޭގެފާނު އެ ގުރްއާނުން ހަނދާންކޮށް ދެއްވާށެވެ! ނަފްސެއްކުޅަ ޢަމަލުތަކުގެ ސަބަބުން، އެ ނަފްސެއް ހަލާކުގެ ތެރެއަށް ހުށަހެޅިދާނެ ކަމަށްޓަކައެވެ. ﷲ ފިޔަވައި އެ ނަފްސަށް އެހީތެރިވާނޭ ފަރާތެއް ނުވެތެވެ. އަދި ޝަފާއަތް ތެރިވާނޭ ފަރާތެއްވެސް ނުވެތެވެ. އަދި ކޮންމެ ފިދުޔަކުން އެ ނަފްސެއް ފިދުޔަ ދިނަސް، އެ ފިދުޔެއް ނުހިއްޕަވާނެތެވެ. އެއުރެންނަކީ އެއުރެން ކުޅަ ޢަމަލުތަކުގެ ސަބަބުން ހަލާކަށް ހުށަހެޅުނު މީހުންނެވެ. އެއުރެންނަށް ކެކިކެކިހުރި ހޫނުފެނުގެ ބުއިމާއި ވޭންދެނިވި އަޒާބު ހުށްޓެވެ. (އެއީ) އެއުރެން ކާފިރުވެ އުޅުނުކަމަށްޓަކައެވެ.","",""],["₆ سورة الأنعام","71","قُلۡ أَنَدۡعُواْ مِن دُونِ ٱللَّهِ مَا لَا يَنفَعُنَا وَلَا يَضُرُّنَا وَنُرَدُّ عَلَىٰٓ أَعۡقَابِنَا بَعۡدَ إِذۡ هَدَىٰنَا ٱللَّهُ كَٱلَّذِي ٱسۡتَهۡوَتۡهُ ٱلشَّيَٰطِينُ فِي ٱلۡأَرۡضِ حَيۡرَانَ لَهُۥٓ أَصۡحَٰبٞ يَدۡعُونَهُۥٓ إِلَى ٱلۡهُدَى ٱئۡتِنَاۗ قُلۡ إِنَّ هُدَى ٱللَّهِ هُوَ ٱلۡهُدَىٰۖ وَأُمِرۡنَا لِنُسۡلِمَ لِرَبِّ ٱلۡعَٰلَمِينَ ٧١","قل أندعو من دون الله ما لا ينفعنا ولا يضرنا ونرد على أعقابنا بعد إذ هدانا الله كالذي استهوته الشياطين في الأرض حيران له أصحاب يدعونه إلى الهدى ائتنا قل إن هدى الله هو الهدى وأمرنا لنسلم لرب العالمين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲ ފިޔަވައި އަހަރެމެންނަށް މަންފާއެއް ނުދޭ، އަދި އަހަރެމެންނަށް ގެއްލުމެއްވެސް ނުދޭ އެއްޗެހިތަކަކަށް އަހަރެމެން ދުއާކުރާނެހެއްޔެވެ؟ އަދި ﷲ އަހަރެމެންނަށް ތެދުމަގު ދެއްކެވުމަށްފަހުގައި (ޝިރުކުގެ ތެރެއަށް) ފަހަށް އެނބުރިދާނޭ ހެއްޔެވެ؟ (އޭރުން ވާނީ) ބިމުގައި ޝައިތާނުންނަށް ހެއްލި، ދެވޭ ނުދެވޭ ތަނެއްނޭނގި، ހައިރާން ވެފައިވާ މީހަކު ފަދައިންނެވެ. އެމީހާއަށް ތެދުމަގަށްގޮވައި ތިމަންމެންގެ ކައިރިޔަށް އަންނާށޭ ބުނާ އެކުވެރިންތަކެއް އޭނާއަށް ވެއެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތެދުމަގަކީ، ﷲގެ ތެދުމަގުކަން ކަށަވަރެވެ. އަދި އަހަރެމެންނަށް އަމުރުކުރައްވާފައިވަނީ އާލަމްތަކުގެ ވެރިރަސްކަލާނގެއަށް ކިޔަމަންވުމަށެވެ.","",""],["₆ سورة الأنعام","72","وَأَنۡ أَقِيمُواْ ٱلصَّلَوٰةَ وَٱتَّقُوهُۚ وَهُوَ ٱلَّذِيٓ إِلَيۡهِ تُحۡشَرُونَ ٧٢","وأن أقيموا الصلاة واتقوه وهو الذي إليه تحشرون","އަދި ނަމާދު ގާއިމުކުރުމަށާއި، އެކަލާނގެއަށް ތަގުވާވެރިވުމަށް އަންގަވާފައިވެއެވެ. ތިޔަބައިމީހުން (ގިޔާމަތް ދުވަހުން) އެއްކުރައްވާހުށީ ހަމައެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["₆ سورة الأنعام","73","وَهُوَ ٱلَّذِي خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضَ بِٱلۡحَقِّۖ وَيَوۡمَ يَقُولُ كُن فَيَكُونُۚ قَوۡلُهُ ٱلۡحَقُّۚ وَلَهُ ٱلۡمُلۡكُ يَوۡمَ يُنفَخُ فِي ٱلصُّورِۚ عَٰلِمُ ٱلۡغَيۡبِ وَٱلشَّهَٰدَةِۚ وَهُوَ ٱلۡحَكِيمُ ٱلۡخَبِيرُ ٧٣","وهو الذي خلق السماوات والأرض بالحق ويوم يقول كن فيكون قوله الحق وله الملك يوم ينفخ في الصور عالم الغيب والشهادة وهو الحكيم الخبير","އެކަލާނގެއީ، ހައްގު ގޮތުގައި އުޑުތަކާއި ބިން ހެއްދެވި ރަސްކަލާނގެއެވެ. އެކަލާނގެ، [ވާށޭ] ވަހީކުރައްވާދުވަސް ހަނދުމަކުރާށެވެ! ފަހެ، އެ ހިނދުން އެކަމެއްވާހުށްޓެވެ. އެކަލާނގެ ބަސްފުޅަކީ ހައްގު ތެދެވެ. އަދި ތާޅަފިލި ފުމެލައްވާ ދުވަހު، ވެރިކަންވަނީ އެކަލާނގެއަށެވެ. އެކަލާނގެއީ، ނުފެންނަކަންތަކާއި، ފެންނަކަންތައް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެއީ، މޮޅަށް ދެނެވޮޑިގެންވާ ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","74","۞وَإِذۡ قَالَ إِبۡرَٰهِيمُ لِأَبِيهِ ءَازَرَ أَتَتَّخِذُ أَصۡنَامًا ءَالِهَةً إِنِّيٓ أَرَىٰكَ وَقَوۡمَكَ فِي ضَلَٰلٖ مُّبِينٖ ٧٤","وإذ قال إبراهيم لأبيه آزر أتتخذ أصناما آلهة إني أراك وقومك في ضلال مبين","އިބްރާހީމްގެފާނު އެކަލޭގެފާނުގެ ބައްޕަ އާޒަރަށް ވިދާޅުވިހިނދު ހަނދުމަކުރާށެވެ! ކަލޭގެފާނު ބުދުތަކެއް އިލާހުން ކަމުގައި ހައްދަވަނީތޯއެވެ؟ ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނަށް ފެނިވަޑައިގަންނަވަނީ ކަލޭގެފާނާއި، ކަލޭގެފާނުގެ ގައުމުގެމީހުން ފާޅުވެގެންވާ މަގުފުރެދުމެއްގައި ވާތީއެވެ.","",""],["₆ سورة الأنعام","75","وَكَذَٰلِكَ نُرِيٓ إِبۡرَٰهِيمَ مَلَكُوتَ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ وَلِيَكُونَ مِنَ ٱلۡمُوقِنِينَ ٧٥","وكذلك نري إبراهيم ملكوت السماوات والأرض وليكون من الموقنين","އަދި ހަމައެފަދައިން، ތިމަންރަސްކަލާނގެ އިބްރާހީމްގެފާނަށް އުޑުތަކާއި، ބިމުގެ މަލަކޫތީވެރިކަން ދެއްކެވީމެވެ. އެއީ ޔަގީންކުރާ މީހުންގެ ތެރެއިން އެކަލޭގެފާނު ވުމަށްޓަކައެވެ.","",""],["₆ سورة الأنعام","76","فَلَمَّا جَنَّ عَلَيۡهِ ٱلَّيۡلُ رَءَا كَوۡكَبٗاۖ قَالَ هَٰذَا رَبِّيۖ فَلَمَّآ أَفَلَ قَالَ لَآ أُحِبُّ ٱلۡأٓفِلِينَ ٧٦","فلما جن عليه الليل رأى كوكبا قال هذا ربي فلما أفل قال لا أحب الآفلين","ދެންފަހެ، ރޭގަނޑުގެ އަނދިރިކަން އެކަލޭގެފާނުގެ މައްޗަށް ފެތުރުނުހިނދު، އެކަލޭގެފާނަށް ތަރިއެއް ފެނިވަޑައިގެން (އެކަލޭގެފާނުގެ ގައުމަށް) ވިދާޅުވިއެވެ. (ތިޔަބައިމީހުން ހީކުރާގޮތުގައި) މިއީ އަހުރެންގެ ވެރިރަސްކަލާނގެއެވެ. ދެންފަހެ، އެތަރި އޮސްފުހުނުހިނދު، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޮސްފުހިދާ ތަކެއްޗަކަށް އަހުރެން ލޯތްބެއްނުކުރަމެވެ.","",""],["₆ سورة الأنعام","77","فَلَمَّا رَءَا ٱلۡقَمَرَ بَازِغٗا قَالَ هَٰذَا رَبِّيۖ فَلَمَّآ أَفَلَ قَالَ لَئِن لَّمۡ يَهۡدِنِي رَبِّي لَأَكُونَنَّ مِنَ ٱلۡقَوۡمِ ٱلضَّآلِّينَ ٧٧","فلما رأى القمر بازغا قال هذا ربي فلما أفل قال لئن لم يهدني ربي لأكونن من القوم الضالين","ދެންފަހެ، ހަނދު އަރައިގެން އަންނަތަން އެކަލޭގެފާނަށް ފެނިވަޑައިގަތްހިނދު (އެއުރެންނަށް) އެކަލޭގެފާނު ވިދާޅުވިއެވެ. (ތިޔަބައިމީހުން ހީކުރާގޮތުގައި) މިއީ އަހުރެންގެ ވެރިރަސްކަލާނގެއެވެ. ދެންފަހެ، އެ ހަނދު އޮސްފުހުނުހިނދު، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަހުރެންގެ ވެރިރަސްކަލާނގެ ތެދުމަގުގައި އަހުރެން ޘާބިތު ނުކުރެއްވިނަމަ، މަގުގެއްލި، ފުރެދިގެންވާ މީހުންގެ ތެރެއިން އަހުރެން ވެއްޖައީސްކަން ކަށަވަރެވެ.","",""],["₆ سورة الأنعام","78","فَلَمَّا رَءَا ٱلشَّمۡسَ بَازِغَةٗ قَالَ هَٰذَا رَبِّي هَٰذَآ أَكۡبَرُۖ فَلَمَّآ أَفَلَتۡ قَالَ يَٰقَوۡمِ إِنِّي بَرِيٓءٞ مِّمَّا تُشۡرِكُونَ ٧٨","فلما رأى الشمس بازغة قال هذا ربي هذا أكبر فلما أفلت قال يا قوم إني بريء مما تشركون","ދެންފަހެ، އިރުއަރައިގެން އަންނަތަން އެކަލޭގެފާނަށް ފެނިވަޑައިގަތްހިނދު (އެއުރެންނަށް) އެކަލޭގެފާނު ވިދާޅުވިއެވެ. (ތިޔަބައިމީހުން ހީކުރާ ގޮތުގައި) މިއީ އަހުރެންގެ ވެރިރަސްކަލާނގެއެވެ. (ހަނދަށްވުރެން) މި، މާބޮޑެވެ. ދެންފަހެ، އެ އިރު އޮސްފުހުނުހިނދު، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން ޝަރީކު ކޮށް ތިޔައުޅޭ (ބުދުތަކާއި، އިރު ހަނދުފަދަ) ތަކެތިން، ހަމަކަށަވަރުން، އަހުރެން ބަރީއަވެގެންވަމެވެ.","",""],["₆ سورة الأنعام","79","إِنِّي وَجَّهۡتُ وَجۡهِيَ لِلَّذِي فَطَرَ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضَ حَنِيفٗاۖ وَمَآ أَنَا۠ مِنَ ٱلۡمُشۡرِكِينَ ٧٩","إني وجهت وجهي للذي فطر السماوات والأرض حنيفا وما أنا من المشركين","ހަމަކަށަވަރުން، (އަޅުކަންކުރުމުގެ ގަސްދުގައި) އަޅުގެ މޫނު ކުރިމަތިކުރަނީ، ބާތިލު ގޮތުން އެއްކިބާވެ، ހައްގުގެ ފަރާތަށް ލެނބިހުރި ޙާލުގައި، އިސްވެދިޔަ ނަމޫނާއެއްނެތި، އުޑުތަކާއި ބިންހެއްދެވި ރަސްކަލާނގެއަށެވެ. އަދި މިއަޅާ މުޝްރިކުންގެ ތެރެއަކުން ނުވަމެވެ.","",""],["₆ سورة الأنعام","80","وَحَآجَّهُۥ قَوۡمُهُۥۚ قَالَ أَتُحَـٰٓجُّوٓنِّي فِي ٱللَّهِ وَقَدۡ هَدَىٰنِۚ وَلَآ أَخَافُ مَا تُشۡرِكُونَ بِهِۦٓ إِلَّآ أَن يَشَآءَ رَبِّي شَيۡـٔٗاۚ وَسِعَ رَبِّي كُلَّ شَيۡءٍ عِلۡمًاۚ أَفَلَا تَتَذَكَّرُونَ ٨٠","وحاجه قومه قال أتحاجوني في الله وقد هدان ولا أخاف ما تشركون به إلا أن يشاء ربي شيئا وسع ربي كل شيء علما أفلا تتذكرون","އެކަލޭގެފާނުގެ ގައުމުގެމީހުން (ދީނާމެދު) އެކަލޭގެފާނާ ޖަދަލު ކޮށް ހަދައިފޫއެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އެކަލާނގެ ތިމަންކަލޭގެފާނަށް ތެދުމަގު ދައްކަވާފައި ވަނިކޮށް، ﷲ އާމެދުގައި ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނާ ޖަދަލުކުރަނީ ހެއްޔެވެ؟ ތިޔަބައިމީހުން އެކަލާނގެއަށް ޝަރީކު ކޮށްއުޅޭ ތަކެއްޗަކަށް ތިމަންކަލޭގެފާނު ބިރުފުޅެއް ނުގަނެއެވެ. އެހެނެއްކަމަކު، ތިމަންކަލޭގެފާނުންގެ ވެރިރަސްކަލާނގެ އިރާދަކުރައްވައިފި ކަމެއް އައިސް ޖެހޭނެތެވެ. ތިމަންކަލޭގެފާނުންގެ ވެރިރަސްކަލާނގެ ދެނެވޮޑިގަތުން ހުރިހައި ތަކެއްޗަކަށް ތަނަވަސް ވެގެންވެއެވެ. ތިޔަބައިމީހުން ފަހެ، ހަނދާންވެސް ނުކުރަނީ ހެއްޔެވެ؟","",""],["₆ سورة الأنعام","81","وَكَيۡفَ أَخَافُ مَآ أَشۡرَكۡتُمۡ وَلَا تَخَافُونَ أَنَّكُمۡ أَشۡرَكۡتُم بِٱللَّهِ مَا لَمۡ يُنَزِّلۡ بِهِۦ عَلَيۡكُمۡ سُلۡطَٰنٗاۚ فَأَيُّ ٱلۡفَرِيقَيۡنِ أَحَقُّ بِٱلۡأَمۡنِۖ إِن كُنتُمۡ تَعۡلَمُونَ ٨١","وكيف أخاف ما أشركتم ولا تخافون أنكم أشركتم بالله ما لم ينزل به عليكم سلطانا فأي الفريقين أحق بالأمن إن كنتم تعلمون","އަދި ތިޔަބައިމީހުން (ﷲއަށް) ޝަރީކުކުޅަ ތަކެއްޗަށް ތިމަންކަލޭގެފާނު ބިރުފުޅު ގަންނާނީ ކޮންފަދަ އަކުންހެއްޔެވެ؟ ތިޔަބައިމީހުންގެ މައްޗަށް އެއާމެދު އެއްވެސް ހުއްޖަތެއް ބާވައިލައްވާފައި ނުވާތަކެތި، ތިޔަބައިމީހުން ﷲއަށް ޝަރީކުކުޅަކަމާމެދު ތިޔަބައިމީހުން ބިރެއްނުގަންނަމުއެވެ. ފަހެ، މި ދެބައިމީހުންކުރެ (އަޒާބުން ސަލާމަތްވެ) އަމާންކަން ލިބުން ހައްގު ކަންބޮޑީ، ކޮންބަޔެއްހެއްޔެވެ؟ ތިޔަބައިމީހުންނަށް (އެބަޔަކު) އެނގޭނަމަ (ނިކަންބުނެދީ ބަލާށެވެ!)","",""],["₆ سورة الأنعام","82","ٱلَّذِينَ ءَامَنُواْ وَلَمۡ يَلۡبِسُوٓاْ إِيمَٰنَهُم بِظُلۡمٍ أُوْلَـٰٓئِكَ لَهُمُ ٱلۡأَمۡنُ وَهُم مُّهۡتَدُونَ ٨٢","الذين آمنوا ولم يلبسوا إيمانهم بظلم أولئك لهم الأمن وهم مهتدون","އެއުރެންނަކީ، އީމާން ވެތިބެ، އެއުރެންގެ އީމާންކަމުގެ ތެރެއަށް (ޝިރުކުގެ) އަނިޔާވެރިކަމެއް ނުލާ މީހުންނެވެ. އަމާންކަންހުރީ، އެއުރެންނަށެވެ. އަދި އެއުރެންނީ ތެދުމަގު ލިބިގެންވާ މީހުންނެވެ.","",""],["₆ سورة الأنعام","83","وَتِلۡكَ حُجَّتُنَآ ءَاتَيۡنَٰهَآ إِبۡرَٰهِيمَ عَلَىٰ قَوۡمِهِۦۚ نَرۡفَعُ دَرَجَٰتٖ مَّن نَّشَآءُۗ إِنَّ رَبَّكَ حَكِيمٌ عَلِيمٞ ٨٣","وتلك حجتنا آتيناها إبراهيم على قومه نرفع درجات من نشاء إن ربك حكيم عليم","އެ ހުރިހާކަމަކީ، ތިމަންރަސްކަލާނގެ (ހަޒުރަތުން އައި) ހުއްޖަތް ތަކެވެ. އެ ހުއްޖަތްތައް، ތިމަންރަސްކަލާނގެ އިބްރާހީމްގެފާނަށް ދެއްވީ، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް ހުށަހެޅުއްވުމަށެވެ. ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާ ބަޔަކު، ދަރަޖަ މަތިވެރިކުރައްވަމެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ޙަކީމްވަންތަ މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","84","وَوَهَبۡنَا لَهُۥٓ إِسۡحَٰقَ وَيَعۡقُوبَۚ كُلًّا هَدَيۡنَاۚ وَنُوحًا هَدَيۡنَا مِن قَبۡلُۖ وَمِن ذُرِّيَّتِهِۦ دَاوُۥدَ وَسُلَيۡمَٰنَ وَأَيُّوبَ وَيُوسُفَ وَمُوسَىٰ وَهَٰرُونَۚ وَكَذَٰلِكَ نَجۡزِي ٱلۡمُحۡسِنِينَ ٨٤","ووهبنا له إسحاق ويعقوب كلا هدينا ونوحا هدينا من قبل ومن ذريته داوود وسليمان وأيوب ويوسف وموسى وهارون وكذلك نجزي المحسنين","ތިމަންރަސްކަލާނގެ، އެކަލޭގެފާނަށް (އެބަހީ: އިބްރާހީމްގެފާނަށް) އިސްޙާގުގެފާނާއި، ޔައުގޫބުގެފާނު ދެއްވީމެވެ. އެއިން ކޮންމެ ބޭކަލަކަށް ތެދުމަގު ދެއްކެވީމެވެ. އަދި އޭގެކުރިން ނޫޙުގެފާނަށް ތެދުމަގު ދެއްކެވީމެވެ. އަދި އެކަލޭގެފާނުންގެ ދަރިކޮޅުން، ދާވޫދުގެފާނާއި، ސުލައިމާނުގެފާނާއި، އައްޔޫބުގެފާނާއި، ޔޫސުފުގެފާނާއި، މޫސާގެފާނާއި، ހާރޫނުގެފާނަށް ތެދުމަގު ދެއްކެވީމެވެ. އަދި އިހްސާން ތެރިންނަށް ތިމަންރަސްކަލާނގެ ޖަޒާދެއްވަނީ އެފަދައިންނެވެ.","",""],["₆ سورة الأنعام","85","وَزَكَرِيَّا وَيَحۡيَىٰ وَعِيسَىٰ وَإِلۡيَاسَۖ كُلّٞ مِّنَ ٱلصَّـٰلِحِينَ ٨٥","وزكريا ويحيى وعيسى وإلياس كل من الصالحين","އަދި ޒަކަރިއްޔާގެފާނާއި، ޔަޙްޔާގެފާނާއި، ޢީސާގެފާނާއި، އިލްޔާސްގެފާނަށް ތެދުމަގު ދެއްކެވީމެވެ. އެއިން ކޮންމެ ބޭކަލަކުމެވަނީ، ސާލިހުންގެ ތެރެއިންނެވެ.","",""],["₆ سورة الأنعام","86","وَإِسۡمَٰعِيلَ وَٱلۡيَسَعَ وَيُونُسَ وَلُوطٗاۚ وَكُلّٗا فَضَّلۡنَا عَلَى ٱلۡعَٰلَمِينَ ٨٦","وإسماعيل واليسع ويونس ولوطا وكلا فضلنا على العالمين","އަދި އިސްމާޢީލުގެފާނާއި، އަލްޔަސަޢުގެފާނާއި، ޔޫނުސްގެފާނާއި، ލޫޠުގެފާނަށް ތެދުމަގު ދެއްކެވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އެއިން ކޮންމެ ބޭކަލަކު އާލަމްތަކުގެ މައްޗަށް މާތްކުރައްވައި އިތުރުކުރެއްވީމެވެ.","",""],["₆ سورة الأنعام","87","وَمِنۡ ءَابَآئِهِمۡ وَذُرِّيَّـٰتِهِمۡ وَإِخۡوَٰنِهِمۡۖ وَٱجۡتَبَيۡنَٰهُمۡ وَهَدَيۡنَٰهُمۡ إِلَىٰ صِرَٰطٖ مُّسۡتَقِيمٖ ٨٧","ومن آبائهم وذرياتهم وإخوانهم واجتبيناهم وهديناهم إلى صراط مستقيم","އަދި އެބޭކަލުންގެ ކާބަފައިކަލުންނާއި، އެބޭކަލުންގެ ދަރިފަސްކޮޅުތަކާއި، އެބޭކަލުންގެ އިޚްވާނުންގެ ތެރެއިން ބަޔަކަށް ތެދުމަގު ދެއްކެވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އެބޭކަލުން ޚިޔާރުކުރައްވައި، އެބޭކަލުންނަށް ސީދާވެގެންވާ ތެދުމަގަށް މަގުދެއްކެވީމެވެ.","",""],["₆ سورة الأنعام","88","ذَٰلِكَ هُدَى ٱللَّهِ يَهۡدِي بِهِۦ مَن يَشَآءُ مِنۡ عِبَادِهِۦۚ وَلَوۡ أَشۡرَكُواْ لَحَبِطَ عَنۡهُم مَّا كَانُواْ يَعۡمَلُونَ ٨٨","ذلك هدى الله يهدي به من يشاء من عباده ولو أشركوا لحبط عنهم ما كانوا يعملون","އެއީ ﷲގެ ތެދުމަގެވެ. އެކަލާނގެ އަޅުންގެ ތެރެއިން އެކަލާނގެ އިރާދަކުރައްވާ ބަޔަކަށް އެއިން ތެދުމަގު ދައްކަވަތެވެ. އެބޭކަލުންވެސް (ﷲއަށް) ޝަރީކުކުރެއްވިނަމަ، އެބޭކަލުން ކޮށްއުޅުއްވި ޢަމަލުތައް ބާތިލު ވީހެވެ.","",""],["₆ سورة الأنعام","89","أُوْلَـٰٓئِكَ ٱلَّذِينَ ءَاتَيۡنَٰهُمُ ٱلۡكِتَٰبَ وَٱلۡحُكۡمَ وَٱلنُّبُوَّةَۚ فَإِن يَكۡفُرۡ بِهَا هَـٰٓؤُلَآءِ فَقَدۡ وَكَّلۡنَا بِهَا قَوۡمٗا لَّيۡسُواْ بِهَا بِكَٰفِرِينَ ٨٩","أولئك الذين آتيناهم الكتاب والحكم والنبوة فإن يكفر بها هؤلاء فقد وكلنا بها قوما ليسوا بها بكافرين","އެބޭކަލުންނަކީ، ތިމަންރަސްކަލާނގެ އެބޭކަލުންނަށް ފޮތާއި، ހިކުމަތާއި، ނަބީކަންދެއްވި ބޭކަލުންނެވެ. މިތިބަމީހުން އެކަންތަކަށް ކާފިރު ވާނަމަ، އެކަންތައްތަކަށް ކާފިރު ނުވާނެ ބަޔަކާ އެކަންތައް ޙަވާލުކުރައްވައިފާހުށީމެވެ.","",""],["₆ سورة الأنعام","90","أُوْلَـٰٓئِكَ ٱلَّذِينَ هَدَى ٱللَّهُۖ فَبِهُدَىٰهُمُ ٱقۡتَدِهۡۗ قُل لَّآ أَسۡـَٔلُكُمۡ عَلَيۡهِ أَجۡرًاۖ إِنۡ هُوَ إِلَّا ذِكۡرَىٰ لِلۡعَٰلَمِينَ ٩٠","أولئك الذين هدى الله فبهداهم اقتده قل لا أسألكم عليه أجرا إن هو إلا ذكرى للعالمين","އެބޭކަލުންނީ، ﷲ، ތެދުމަގު ދެއްކެވި ބޭކަލުންނެވެ. ފަހެ، އެބޭކަލުންގެ ތެދުމަގާ ކަލޭގެފާނު ތަބާ ވެވަޑައިގަންނަވާށެވެ! ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެ ގުރްއާންގެ މައްޗަށް އުޖޫރައެއް ދިނުމަކަށް، ތިޔަބައިމީހުންގެ ކިބަޔަކުން އަހުރެން ނޭދެމެވެ. އެ ގުރްއާނަކީ، އާލަމް ތަކަށްވާ ހަނދާން ކޮށްދިނުމެއް ކަމުގައި މެނުވީ ނުވެއެވެ.","",""],["₆ سورة الأنعام","91","وَمَا قَدَرُواْ ٱللَّهَ حَقَّ قَدۡرِهِۦٓ إِذۡ قَالُواْ مَآ أَنزَلَ ٱللَّهُ عَلَىٰ بَشَرٖ مِّن شَيۡءٖۗ قُلۡ مَنۡ أَنزَلَ ٱلۡكِتَٰبَ ٱلَّذِي جَآءَ بِهِۦ مُوسَىٰ نُورٗا وَهُدٗى لِّلنَّاسِۖ تَجۡعَلُونَهُۥ قَرَاطِيسَ تُبۡدُونَهَا وَتُخۡفُونَ كَثِيرٗاۖ وَعُلِّمۡتُم مَّا لَمۡ تَعۡلَمُوٓاْ أَنتُمۡ وَلَآ ءَابَآؤُكُمۡۖ قُلِ ٱللَّهُۖ ثُمَّ ذَرۡهُمۡ فِي خَوۡضِهِمۡ يَلۡعَبُونَ ٩١","وما قدروا الله حق قدره إذ قالوا ما أنزل الله على بشر من شيء قل من أنزل الكتاب الذي جاء به موسى نورا وهدى للناس تجعلونه قراطيس تبدونها وتخفون كثيرا وعلمتم ما لم تعلموا أنتم ولا آباؤكم قل الله ثم ذرهم في خوضهم يلعبون","ﷲއަށް ގަދަރުކުރުން ހައްގު ވެގެންވާ ގޮތުގައި އެއުރެން (އެބަހީ: ޔަހޫދީން) އެކަލާނގެއަށް ގަދަރެއް ނުކުރެތެވެ. އެހެނީ، އެއުރެންބުނީ، އާދަމުގެދަރިޔަކަށް ﷲއެއްވެސް އެއްޗެއް ބާވައެއް ނުލައްވަތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! (ތިޔަހެންވިއްޔާ) މީސްތަކުންނަށް ނޫރެއް ކަމުގައްޔާއި، ހިދާޔަތެއް ކަމުގައި، މޫސާގެފާނު އެ ގެންނެވި ފޮތް ބާވައިލެއްވީ ކާކުހެއްޔެވެ؟ ތިޔަބައިމީހުން އެފޮތް ހަދައިގެން އުޅެނީ (ވަކިވަކި) ކަރުދާސްތަކެއް ކަމުގައެވެ. އެއިން ބައެއް ފާޅުކޮށް، އޭގެ ގިނަބައި، ތިޔަބައިމީހުން ވަންހަނާ ކުރަމުއެވެ. އަދި ތިޔަބައިމީހުންނަށާއި، ތިޔަބައިމީހުންގެ ކާބަފައިންނަށްވެސް އެނގިފައިނުވާ ތަކެތި (ގުރްއާނުން) ތިޔަބައިމީހުންނަށް ވަނީ އަންގަވައި ދެއްވާފައެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! (އެތަކެތި ބާވައިލެއްވީ) ﷲއެވެ. ދެން އެއުރެންގެ ބާތިލު ވާހަކަތަކުގެ ތެރޭގައި ކުޅެކުޅެ ތިބެން އެއުރެން ދޫކޮށްލައްވާށެވެ!","",""],["₆ سورة الأنعام","92","وَهَٰذَا كِتَٰبٌ أَنزَلۡنَٰهُ مُبَارَكٞ مُّصَدِّقُ ٱلَّذِي بَيۡنَ يَدَيۡهِ وَلِتُنذِرَ أُمَّ ٱلۡقُرَىٰ وَمَنۡ حَوۡلَهَاۚ وَٱلَّذِينَ يُؤۡمِنُونَ بِٱلۡأٓخِرَةِ يُؤۡمِنُونَ بِهِۦۖ وَهُمۡ عَلَىٰ صَلَاتِهِمۡ يُحَافِظُونَ ٩٢","وهذا كتاب أنزلناه مبارك مصدق الذي بين يديه ولتنذر أم القرى ومن حولها والذين يؤمنون بالآخرة يؤمنون به وهم على صلاتهم يحافظون","މި ގުރްއާނަކީ، ތިމަންރަސްކަލާނގެ ބާވައިލެއްވި ފޮތެކެވެ. ބަރަކާތްތެރި ފޮތެކެވެ. ކުރީގެ ފޮތްތައް ތެދުކުރާ ފޮތެކެވެ. (އެފޮތް ބާވައިލެއްވީ) މައިރަށުގެ (އެބަހީ: މައްކާގެ) އަހުލުވެރިންނާއި، އެތާނގެ ވަށައިގެންވާ މީހުންނަށް ކަލޭގެފާނު އިންޒާރުކުރެއްވުމަށްޓަކައެވެ. އަދި އާޚިރަތް ދުވަހަށް އީމާންވާ މީހުން އެ ފޮތަށް އީމާންވާނެތެވެ. އަދި އެއުރެން އެއުރެންގެ ނަމާދަށް ރައްކާތެރިވާނެތެވެ.","",""],["₆ سورة الأنعام","93","وَمَنۡ أَظۡلَمُ مِمَّنِ ٱفۡتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَوۡ قَالَ أُوحِيَ إِلَيَّ وَلَمۡ يُوحَ إِلَيۡهِ شَيۡءٞ وَمَن قَالَ سَأُنزِلُ مِثۡلَ مَآ أَنزَلَ ٱللَّهُۗ وَلَوۡ تَرَىٰٓ إِذِ ٱلظَّـٰلِمُونَ فِي غَمَرَٰتِ ٱلۡمَوۡتِ وَٱلۡمَلَـٰٓئِكَةُ بَاسِطُوٓاْ أَيۡدِيهِمۡ أَخۡرِجُوٓاْ أَنفُسَكُمُۖ ٱلۡيَوۡمَ تُجۡزَوۡنَ عَذَابَ ٱلۡهُونِ بِمَا كُنتُمۡ تَقُولُونَ عَلَى ٱللَّهِ غَيۡرَ ٱلۡحَقِّ وَكُنتُمۡ عَنۡ ءَايَٰتِهِۦ تَسۡتَكۡبِرُونَ ٩٣","ومن أظلم ممن افترى على الله كذبا أو قال أوحي إلي ولم يوح إليه شيء ومن قال سأنزل مثل ما أنزل الله ولو ترى إذ الظالمون في غمرات الموت والملائكة باسطو أيديهم أخرجوا أنفسكم اليوم تجزون عذاب الهون بما كنتم تقولون على الله غير الحق وكنتم عن آياته تستكبرون","ﷲއާމެދު ހަދައިގެން ދޮގެއްބުނި މީހަކަށްވުރެން، ނުވަތަ އެމީހަކަށް އެއްވެސް އެއްޗެއް ވަހީ ނުކުރައްވަނީސް، ތިމަންނާއަށް ވަހީކުރައްވައިފިއޭ ބުނި މީހަކަށްވުރެން އަދި ﷲ ބާވައިލެއްވި ފަދަތަކެތި ތިމަންވެސް ބާވައިލައިފާނަމޭ ބުނި މީހަކަށްވުރެން ބޮޑު އަނިޔާވެރިޔަކީ ކާކުހެއްޔެވެ؟ އަނިޔާވެރިން މަރުގެ ސަކަރާތުގައި އުޅޭހިނދު، ކަލޭގެފާނަށް ފެނިވަޑައިގަންނަވާނެ ނަމައެވެ. މަލާއިކަތުން އެހިނދު ތިއްބަވާނީ އެބޭކަލުންގެ އަތްޕުޅު ދިއްކުރައްވައިގެންނެވެ. (އަދި ވިދާޅުވާނެތެވެ.) ތިޔަބައިމީހުންގެ ފުރާނަތައް ނެރޭށެވެ! މިއަދު ތިޔަބައިމީހުންނަށް އިހާނަތްތެރި އަޒާބުން ޖަޒާ ދެއްވާނެތެވެ. (އެއީ) ތިޔަބައިމީހުން، ﷲއާމެދު ބުނެއުޅުނު ހައްގު ނޫން ބަސްތަކުގެ ސަބަބުންނާއި، އެކަލާނގެ އާޔަތްތަކަށް (އީމާން ނުވެ) ބޮޑާވެގަނެގެން އުޅުނުކަމުގެ ސަބަބުންނެވެ.","",""],["₆ سورة الأنعام","94","وَلَقَدۡ جِئۡتُمُونَا فُرَٰدَىٰ كَمَا خَلَقۡنَٰكُمۡ أَوَّلَ مَرَّةٖ وَتَرَكۡتُم مَّا خَوَّلۡنَٰكُمۡ وَرَآءَ ظُهُورِكُمۡۖ وَمَا نَرَىٰ مَعَكُمۡ شُفَعَآءَكُمُ ٱلَّذِينَ زَعَمۡتُمۡ أَنَّهُمۡ فِيكُمۡ شُرَكَـٰٓؤُاْۚ لَقَد تَّقَطَّعَ بَيۡنَكُمۡ وَضَلَّ عَنكُم مَّا كُنتُمۡ تَزۡعُمُونَ ٩٤","ولقد جئتمونا فرادى كما خلقناكم أول مرة وتركتم ما خولناكم وراء ظهوركم وما نرى معكم شفعاءكم الذين زعمتم أنهم فيكم شركاء لقد تقطع بينكم وضل عنكم ما كنتم تزعمون","އަދި (މަހުޝަރަށް ފޮނުއްވާހިނދު، އެއުރެންނަށް އަންގަވާނެތެވެ.) ތިޔަބައިމީހުން، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ތިޔައައީ، އެކަހެރީންގެ ގޮތުގައެވެ. ފުރަތަމަފަހަރު ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން ހެއްދެވި ފަދައިންނެވެ. އަދި ތިޔަބައިމީހުންނަށް، ތިމަންރަސްކަލާނގެ ދެއްވި ތަކެތި ތިޔަބައިމީހުންގެ ފަހަތަށް ދޫކޮށްފައެވެ. ތިޔަބައިމީހުންނާއެކު، ތިޔަބައިމީހުންގެ ޝަފާއަތް ތެރިން ވަނިކޮށެއް ނުފެނެއެވެ. އެތަކެއްޗަކީ، ތިޔަބައިމީހުންގެ ތެރޭގައި ޝަރީކުން ކަމަށް ތިޔަބައިމީހުން ހީކޮށްގެން އުޅުނު ތަކެއްޗެވެ. ތިޔަބައިމީހުންނާ އެތަކެއްޗާ ދެމެދުގައިވާ ގުޅުންތައް ކެނޑި، ވަކިވަކިވެއްޖެކަން ކަށަވަރެވެ. އަދި (ޝަފާއަތް ތެރިވާނެކަމަށް) ތިޔަބައިމީހުން ހީކޮށްއުޅުނު ތަކެތި، ތިޔަބައިމީހުންގެ ކިބައިން ގެއްލިއްޖެއެވެ.","",""],["₆ سورة الأنعام","95","۞إِنَّ ٱللَّهَ فَالِقُ ٱلۡحَبِّ وَٱلنَّوَىٰۖ يُخۡرِجُ ٱلۡحَيَّ مِنَ ٱلۡمَيِّتِ وَمُخۡرِجُ ٱلۡمَيِّتِ مِنَ ٱلۡحَيِّۚ ذَٰلِكُمُ ٱللَّهُۖ فَأَنَّىٰ تُؤۡفَكُونَ ٩٥","إن الله فالق الحب والنوى يخرج الحي من الميت ومخرج الميت من الحي ذلكم الله فأنى تؤفكون","ހަމަކަށަވަރުން، ﷲއީ، އޮށްޓަރާއި، އޮށުން ގަސް ފަޅުއްވާ ރަސްކަލާނގެއެވެ. އެކަލާނގެއީ، މަރުވެފައިވާ ތަކެތިން ދިރޭ ތަކެތި ނެރުއްވާ ރަސްކަލާނގެއެވެ. އަދި ދިރޭ ތަކެތިން، މަރުވެފައިވާ ތަކެތި ނެރުއްވާ ރަސްކަލާނގެއެވެ. އެއީ ﷲއެވެ. ފަހެ، ތިޔަބައިމީހުން (އީމާންކަމުން) އެއްކިބާވެގަންނަނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["₆ سورة الأنعام","96","فَالِقُ ٱلۡإِصۡبَاحِ وَجَعَلَ ٱلَّيۡلَ سَكَنٗا وَٱلشَّمۡسَ وَٱلۡقَمَرَ حُسۡبَانٗاۚ ذَٰلِكَ تَقۡدِيرُ ٱلۡعَزِيزِ ٱلۡعَلِيمِ ٩٦","فالق الإصباح وجعل الليل سكنا والشمس والقمر حسبانا ذلك تقدير العزيز العليم","އެކަލާނގެއީ، ފަތިހުގެ އަލިކަން ނެރުއްވި ރަސްކަލާނގެއެވެ. އަދި ހަމަހިމޭންކަމުގެ ވަގުތެއް ކަމުގައި، ރޭގަނޑު ލެއްވި ރަސްކަލާނގެއެވެ. އަދި (ވަގުތު ދެނެގަތުމަށްޓަކައި) ހިސާބެއްކަމުގައި އިރާއި، ހަނދު ލެއްވި ރަސްކަލާނގެއެވެ. އެއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ގަދަފަދަވަންތަ ރަސްކަލާނގެ މިންވަރު ކުރެއްވުމެވެ.","",""],["₆ سورة الأنعام","97","وَهُوَ ٱلَّذِي جَعَلَ لَكُمُ ٱلنُّجُومَ لِتَهۡتَدُواْ بِهَا فِي ظُلُمَٰتِ ٱلۡبَرِّ وَٱلۡبَحۡرِۗ قَدۡ فَصَّلۡنَا ٱلۡأٓيَٰتِ لِقَوۡمٖ يَعۡلَمُونَ ٩٧","وهو الذي جعل لكم النجوم لتهتدوا بها في ظلمات البر والبحر قد فصلنا الآيات لقوم يعلمون","އަދި އެކަލާނގެއީ، ތިޔަބައިމީހުންނަށްޓަކައި ތަރިތައް ލެއްވި ރަސްކަލާނގެއެވެ. (އެއީ) ތިޔަބައިމީހުން، އެއިން އެއްގަމާއި، ކަނޑުގައި (ރޭގަނޑުގެ) އަނދިރިކަމުގެ ތެރޭގައި، މަގު ދެނެގަތުމަށްޓަކައެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އާޔަތްތައް ވަކިވަކިން ބަޔާންކޮށްދެއްވީ، ދަންނަ ބަޔަކަށެވެ.","",""],["₆ سورة الأنعام","98","وَهُوَ ٱلَّذِيٓ أَنشَأَكُم مِّن نَّفۡسٖ وَٰحِدَةٖ فَمُسۡتَقَرّٞ وَمُسۡتَوۡدَعٞۗ قَدۡ فَصَّلۡنَا ٱلۡأٓيَٰتِ لِقَوۡمٖ يَفۡقَهُونَ ٩٨","وهو الذي أنشأكم من نفس واحدة فمستقر ومستودع قد فصلنا الآيات لقوم يفقهون","އަދި އެކަލާނގެއީ، އެންމެ ނަފްސަކުން (އެބަހީ: އާދަމުގެފާނުގެ ކިބައިން) ތިޔަބައިމީހުން އުފެއްދެވި ރަސްކަލާނގެއެވެ. ފަހެ، ގަރާރުވެ ތިބެވޭނެ ތަނަކާއި، ރައްކާކުރަން ލެވޭތަނެއް (އެބަހީ: ކަށްވަޅު ތިޔަބައިމީހުންނަށް) ވެއެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އާޔަތްތައް ވަކިވަކިން ބަޔާންކޮށްދެއްވީ ވިސްނާ ބަޔަކަށެވެ.","",""],["₆ سورة الأنعام","99","وَهُوَ ٱلَّذِيٓ أَنزَلَ مِنَ ٱلسَّمَآءِ مَآءٗ فَأَخۡرَجۡنَا بِهِۦ نَبَاتَ كُلِّ شَيۡءٖ فَأَخۡرَجۡنَا مِنۡهُ خَضِرٗا نُّخۡرِجُ مِنۡهُ حَبّٗا مُّتَرَاكِبٗا وَمِنَ ٱلنَّخۡلِ مِن طَلۡعِهَا قِنۡوَانٞ دَانِيَةٞ وَجَنَّـٰتٖ مِّنۡ أَعۡنَابٖ وَٱلزَّيۡتُونَ وَٱلرُّمَّانَ مُشۡتَبِهٗا وَغَيۡرَ مُتَشَٰبِهٍۗ ٱنظُرُوٓاْ إِلَىٰ ثَمَرِهِۦٓ إِذَآ أَثۡمَرَ وَيَنۡعِهِۦٓۚ إِنَّ فِي ذَٰلِكُمۡ لَأٓيَٰتٖ لِّقَوۡمٖ يُؤۡمِنُونَ ٩٩","وهو الذي أنزل من السماء ماء فأخرجنا به نبات كل شيء فأخرجنا منه خضرا نخرج منه حبا متراكبا ومن النخل من طلعها قنوان دانية وجنات من أعناب والزيتون والرمان مشتبها وغير متشابه انظروا إلى ثمره إذا أثمر وينعه إن في ذلكم لآيات لقوم يؤمنون","އަދި އެކަލާނގެއީ، އުޑުން ފެންވެއްސެވި ރަސްކަލާނގެއެވެ. އެފެނުން ތިމަންރަސްކަލާނގެ ހުރިހާ ބާވަތެއްގެ ގަސް ފެޅުއްވީމެވެ. އަދި އެ ގަސްގަހާގެހިން ރޯ ފެހިކުލައިގެ ގޮފިތައް ނެރުއްވައި، އެއިން މަތިމައްޗަށް ހުންނަ އޮށްޓަރުތައް ނެރުއްވަމެވެ. އަދި ކަދުރުރުކުގެ އެތްތަކުން ގާތްގާތުން އިހާތައް ނެރުއްވަމެވެ. އަދި މޭބިސްކަދުރާއި، ޒައިތޫންޏާއި، އަންނާރުގެ ބަގީޗާތައް ނެރުއްވަމެވެ. (އެތަކެތި) އެއްވައްތަރުވެގެންވާ ޙާލު ގައްޔާއި، އެއްވައްތަރު ވެގެންނުވާ ޙާލު ގައެވެ. ތިޔަބައިމީހުން އޭގެ މޭވާ ނުކުންނަހިނދު އެ މޭވާއަށާއި، އެ މޭވާ ފައްކާވާ ފައްކާވުމަށް (އިބްރަތްގެ ނަޡަރަކުން) ބަލާށެވެ! ހަމަކަށަވަރުން، އީމާންވާ ބަޔަކަށް އެކަންތަކުގައި ދަލީލުތަކެއް ވެއެވެ.","",""],["₆ سورة الأنعام","100","وَجَعَلُواْ لِلَّهِ شُرَكَآءَ ٱلۡجِنَّ وَخَلَقَهُمۡۖ وَخَرَقُواْ لَهُۥ بَنِينَ وَبَنَٰتِۭ بِغَيۡرِ عِلۡمٖۚ سُبۡحَٰنَهُۥ وَتَعَٰلَىٰ عَمَّا يَصِفُونَ ١٠٠","وجعلوا لله شركاء الجن وخلقهم وخرقوا له بنين وبنات بغير علم سبحانه وتعالى عما يصفون","ޖިންނީންނަކީ، ﷲއަށްވާ ޝަރީކު ންތަކެއްކަމުގައި ހަދައިގެން އެއުރެން އުޅުނޫވެ. އެ ޖިންނީންވެސް ހެއްދެވީ އެކަލާނގެއެވެ. އަދި އެއްވެސް އެނގުމަކާނުލައި، އެކަލާނގެއަށް ދަރިދަރިކަލުންނާއި، ދަރިދަރިކަނބަލުން ވާކަމަށް ހަދައިގެން އެއުރެން އުޅުނޫއެވެ. އެއުރެން އެސިފަކުރާ ކަންތަކުން، އެކަލާނގެ ހުސްތާހިރުވެ މަތިވެރިވެވޮޑިގެންވެއެވެ.","",""],["₆ سورة الأنعام","101","بَدِيعُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِۖ أَنَّىٰ يَكُونُ لَهُۥ وَلَدٞ وَلَمۡ تَكُن لَّهُۥ صَٰحِبَةٞۖ وَخَلَقَ كُلَّ شَيۡءٖۖ وَهُوَ بِكُلِّ شَيۡءٍ عَلِيمٞ ١٠١","بديع السماوات والأرض أنى يكون له ولد ولم تكن له صاحبة وخلق كل شيء وهو بكل شيء عليم","(އެކަލާނގެއީ) އިސްވެދިޔަ މިސާލެއްނެތި، އުޑުތަކާއި ބިންހެއްދެވި ރަސްކަލާނގެއެވެ. އެކަލާނގެއަށް، ދަރިކަލަކު ވާނީ ކިހިނަކުން ހެއްޔެވެ؟ އެކަލާނގެއަށް އަނބިކަނބަލަކުވެސް ނުވެއެވެ. އަދި ހުރިހާ ތަކެއްޗެއް ހެއްދެވީ، އެކަލާނގެއެވެ. އަދި އެކަލާނގެއީ، ހުރިހާ ތަކެއްޗެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","102","ذَٰلِكُمُ ٱللَّهُ رَبُّكُمۡۖ لَآ إِلَٰهَ إِلَّا هُوَۖ خَٰلِقُ كُلِّ شَيۡءٖ فَٱعۡبُدُوهُۚ وَهُوَ عَلَىٰ كُلِّ شَيۡءٖ وَكِيلٞ ١٠٢","ذلكم الله ربكم لا إله إلا هو خالق كل شيء فاعبدوه وهو على كل شيء وكيل","އެއީ ﷲއެވެ. ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއެވެ. އެކަލާނގެ މެނުވީ ހައްގު ވެގެން އަޅުކަމެއްވެވޭ އިލާހަކުނުވެއެވެ. (އެކަލާނގެއީ) ހުރިހާ ތަކެއްޗެއް ހެއްދެވި ރަސްކަލާނގެއެވެ. ފަހެ، ތިޔަބައިމީހުން އެކަލާނގެއަށް އަޅުކަން ކުރާށެވެ! އަދި އެކަލާނގެއީ، ހުރިހާ ތަކެއްޗެއް ރައްކާތެރި ކުރައްވާ ބަލަހައްޓަވާ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","103","لَّا تُدۡرِكُهُ ٱلۡأَبۡصَٰرُ وَهُوَ يُدۡرِكُ ٱلۡأَبۡصَٰرَۖ وَهُوَ ٱللَّطِيفُ ٱلۡخَبِيرُ ١٠٣","لا تدركه الأبصار وهو يدرك الأبصار وهو اللطيف الخبير","އެކަލާނގެ ޛާތުފުޅު (ދުނިޔެމަތީގައި) ލޯތަކަކަށް ނުފެންނާނެތެވެ. އެކަލާނގެ، އެ ލޯތައް ދެކެވޮޑިގެންވެތެވެ. އަދި އެކަލާނގެއީ، އޯގާވަންތަކަން ބޮޑު، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","104","قَدۡ جَآءَكُم بَصَآئِرُ مِن رَّبِّكُمۡۖ فَمَنۡ أَبۡصَرَ فَلِنَفۡسِهِۦۖ وَمَنۡ عَمِيَ فَعَلَيۡهَاۚ وَمَآ أَنَا۠ عَلَيۡكُم بِحَفِيظٖ ١٠٤","قد جاءكم بصائر من ربكم فمن أبصر فلنفسه ومن عمي فعليها وما أنا عليكم بحفيظ","(ކަލޭގެފާނު ވިދާޅުވާށެވެ!) ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން، ތިޔަބައިމީހުންގެ ގާތަށް ދަލީލުތަކެއް އަތުވެއްޖެކަން ކަށަވަރެވެ. ފަހެ، އެ ދަލީލުތައް ދެކެފިމީހާ (ދަންނާށެވެ!) އެކަމުގެ މަންފާހުރީ، ހަމަ އެމީހާގެ އަމިއްލަ ނަފްސަށެވެ. އަދި އެ ދަލީލުތައް ނުދެކި، ކަނުވެގެންފި މީހާ، އެ ގެއްލުންދެނީވެސް ހަމަ އެމީހާގެ އަމިއްލަ ނަފްސަށެވެ. އަދި ތިޔަބައިމީހުންގެ މައްޗަށް ހުރި ފާރަވެރިޔަކު ކަމުގައި ތިމަންކަލޭގެފާނު ނުވަމެވެ.","",""],["₆ سورة الأنعام","105","وَكَذَٰلِكَ نُصَرِّفُ ٱلۡأٓيَٰتِ وَلِيَقُولُواْ دَرَسۡتَ وَلِنُبَيِّنَهُۥ لِقَوۡمٖ يَعۡلَمُونَ ١٠٥","وكذلك نصرف الآيات وليقولوا درست ولنبينه لقوم يعلمون","ހަމައެފަދައިން، ތިމަންރަސްކަލާނގެ އާޔަތްތައް އެކިގޮތްގޮތަށް ބަޔާންކޮށް ދެއްވަމެވެ. އެންމެފަހުން އެ ކާފިރުވި މީހުން ބުނެތެވެ. ކަލޭގެފާނު (އެ އާޔަތްތައް އިހުގެ ފޮތްފޮތުން) ދަސްފުޅު ކުރެއްވީއެވެ. އަދި ތިމަންރަސްކަލާނގެ އެ އާޔަތްތައް (ބަޔާންކޮށްދެއްވަނީ) ދަންނާނޭ ބަޔަކަށް ހާމަކޮށްދެއްވުމަށެވެ.","",""],["₆ سورة الأنعام","106","ٱتَّبِعۡ مَآ أُوحِيَ إِلَيۡكَ مِن رَّبِّكَۖ لَآ إِلَٰهَ إِلَّا هُوَۖ وَأَعۡرِضۡ عَنِ ٱلۡمُشۡرِكِينَ ١٠٦","اتبع ما أوحي إليك من ربك لا إله إلا هو وأعرض عن المشركين","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ކަލޭގެފާނަށް ވަހީކުރެއްވި ތަކެއްޗަށް ތަބާ ވެވަޑައިގަންނަވާށެވެ! އެކަލާނގެމެނުވީ، ހައްގު ވެގެން އަޅުކަމެއްވެވޭ އިލާހަކު ނުވެއެވެ. އަދި ކަލޭގެފާނު މުޝްރިކުންނާ އެއްކިބާވެވަޑައި ގަންނަވާށެވެ!","",""],["₆ سورة الأنعام","107","وَلَوۡ شَآءَ ٱللَّهُ مَآ أَشۡرَكُواْۗ وَمَا جَعَلۡنَٰكَ عَلَيۡهِمۡ حَفِيظٗاۖ وَمَآ أَنتَ عَلَيۡهِم بِوَكِيلٖ ١٠٧","ولو شاء الله ما أشركوا وما جعلناك عليهم حفيظا وما أنت عليهم بوكيل","އަދި ﷲ އިރާދަކުރެއްވިނަމަ، އެއުރެން ޝަރީކެއް ނުކުޅައީހެވެ. އަދި އެއުރެންގެ މައްޗަށް ފާރަވެރިޔަކު ކަމުގައި ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ނުލައްވަމެވެ. އަދި ކަލޭގެފާނަކީ، އެއުރެންގެ ކަންތައްތައް ޙަވާލުކުރައްވާފައިވާ ވަކީލަކު ކަމުގައިވެސް ނުވެއެވެ.","",""],["₆ سورة الأنعام","108","وَلَا تَسُبُّواْ ٱلَّذِينَ يَدۡعُونَ مِن دُونِ ٱللَّهِ فَيَسُبُّواْ ٱللَّهَ عَدۡوَۢا بِغَيۡرِ عِلۡمٖۗ كَذَٰلِكَ زَيَّنَّا لِكُلِّ أُمَّةٍ عَمَلَهُمۡ ثُمَّ إِلَىٰ رَبِّهِم مَّرۡجِعُهُمۡ فَيُنَبِّئُهُم بِمَا كَانُواْ يَعۡمَلُونَ ١٠٨","ولا تسبوا الذين يدعون من دون الله فيسبوا الله عدوا بغير علم كذلك زينا لكل أمة عملهم ثم إلى ربهم مرجعهم فينبئهم بما كانوا يعملون","ﷲ ދޫކޮށް، އެއުރެން އަޅުކަންކުރާ ތަކެއްޗަށް ތިޔަބައިމީހުން އެއްޗެހިގޮވައި ނަހަދާށެވެ! އޭރުން ނޭނގިތިބެ އެއުރެން އަދާވަތް ތެރިކަމުގެ ގޮތުން ﷲއަށް އެއްޗެހި ގޮވައިފާނެތެވެ. ހަމައެފަދައިން، ކޮންމެ އުއްމަތަކަށްމެ އެބަޔެއްގެ ޢަމަލު، ތިމަންރަސްކަލާނގެ ޒީނަތްތެރިކޮށް ދެއްކެވީމެވެ. ދެން އެއަށްފަހު، އެއުރެން ރުޖޫއަ ވާހުށީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށެވެ. ދެން އެއުރެން ކޮށްއުޅުނު ޢަމަލުތަކުގެ ވާހަކައިން، އެކަލާނގެ އެއުރެންނަށް ޚަބަރު އަންގަވާނެތެވެ.","",""],["₆ سورة الأنعام","109","وَأَقۡسَمُواْ بِٱللَّهِ جَهۡدَ أَيۡمَٰنِهِمۡ لَئِن جَآءَتۡهُمۡ ءَايَةٞ لَّيُؤۡمِنُنَّ بِهَاۚ قُلۡ إِنَّمَا ٱلۡأٓيَٰتُ عِندَ ٱللَّهِۖ وَمَا يُشۡعِرُكُمۡ أَنَّهَآ إِذَا جَآءَتۡ لَا يُؤۡمِنُونَ ١٠٩","وأقسموا بالله جهد أيمانهم لئن جاءتهم آية ليؤمنن بها قل إنما الآيات عند الله وما يشعركم أنها إذا جاءت لا يؤمنون","އެ (ކާފިރުވި) މީހުންގެ ގާތަށް އާޔަތެއް (އެބަހީ: މުއުޖިޒާއެއް) އަތުވެއްޖެނަމަ، އެއަށް ހަމަކަށަވަރުން، އީމާން ވާނެކަމަށް އެއުރެންނަށް ވެވުނުހައި ގަދައެއްކޮށް ﷲ ގަންދީ ހުވާކުރެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، އާޔަތްތައް ވަނީ، ﷲގެ ހަޒުރަތު ގައެވެ. އެ އާޔަތްތައް އަތުވެއްޖެނަމަ، (އެއުރެން ޢަމަލުކުރާނޭގޮތެއް) ތިޔަބައިމީހުންނަށް އަންގައިދެނީ ކޮން އެއްޗެއް ހެއްޔެވެ؟ އެއުރެން އީމާނެއް ނުވާނެތެވެ.","",""],["₆ سورة الأنعام","110","وَنُقَلِّبُ أَفۡـِٔدَتَهُمۡ وَأَبۡصَٰرَهُمۡ كَمَا لَمۡ يُؤۡمِنُواْ بِهِۦٓ أَوَّلَ مَرَّةٖ وَنَذَرُهُمۡ فِي طُغۡيَٰنِهِمۡ يَعۡمَهُونَ ١١٠","ونقلب أفئدتهم وأبصارهم كما لم يؤمنوا به أول مرة ونذرهم في طغيانهم يعمهون","ތިމަންރަސްކަލާނގެ އެއުރެންގެ ހިތްތަކާއި، ލޯތައް (ހައްގުގެ މަގުން) އެއްކިބާކުރައްވަމެވެ. އެއުރެން އެ އާޔަތްތަކަށް ފުރަތަމަ ފަހަރުވެސް، އީމާން ނުވި ފަދައިން (އީމާނެއް ނުވާނެތެވެ.) އަދި ދެފުށުއެޅި ތިބޭ ޙާލެއްގައި، އެއުރެންގެ ފުރެދުމުގެ ތެރެޔަށް، ތިމަންރަސްކަލާނގެ އެއުރެން ދޫކޮށްލައްވާހުށީމެވެ.","",""],["₆ سورة الأنعام","111","۞وَلَوۡ أَنَّنَا نَزَّلۡنَآ إِلَيۡهِمُ ٱلۡمَلَـٰٓئِكَةَ وَكَلَّمَهُمُ ٱلۡمَوۡتَىٰ وَحَشَرۡنَا عَلَيۡهِمۡ كُلَّ شَيۡءٖ قُبُلٗا مَّا كَانُواْ لِيُؤۡمِنُوٓاْ إِلَّآ أَن يَشَآءَ ٱللَّهُ وَلَٰكِنَّ أَكۡثَرَهُمۡ يَجۡهَلُونَ ١١١","ولو أننا نزلنا إليهم الملائكة وكلمهم الموتى وحشرنا عليهم كل شيء قبلا ما كانوا ليؤمنوا إلا أن يشاء الله ولكن أكثرهم يجهلون","ތިމަންރަސްކަލާނގެ އެއުރެންގެ ގާތަށް މަލާއިކަތުން ބާވައިލެއްވި ނަމަވެސް، އަދި މަރުވެފައިވާ މީހުން އެއުރެންނާ ވާހަކަ ދެއްކި ނަމަވެސް، އަދި (އެއުރެން އެދުނު) ހުރިހާ އެއްޗެއް އެއުރެންގެ ކުރިމައްޗަށް ޖަމާކޮށްދެއްވިނަމަވެސް، ﷲ އިރާދަކުރެއްވިއްޔާ މެނުވީ، އެއުރެން އީމާން ވާނެ ބަޔަކު ކަމުގައެއް ނުވެތެވެ. އެހެނެއްކަމަކު، އޭގެ ގިނަމީހުން (އެކަމެއް) ނުދަނެތެވެ.","",""],["₆ سورة الأنعام","112","وَكَذَٰلِكَ جَعَلۡنَا لِكُلِّ نَبِيٍّ عَدُوّٗا شَيَٰطِينَ ٱلۡإِنسِ وَٱلۡجِنِّ يُوحِي بَعۡضُهُمۡ إِلَىٰ بَعۡضٖ زُخۡرُفَ ٱلۡقَوۡلِ غُرُورٗاۚ وَلَوۡ شَآءَ رَبُّكَ مَا فَعَلُوهُۖ فَذَرۡهُمۡ وَمَا يَفۡتَرُونَ ١١٢","وكذلك جعلنا لكل نبي عدوا شياطين الإنس والجن يوحي بعضهم إلى بعض زخرف القول غرورا ولو شاء ربك ما فعلوه فذرهم وما يفترون","ހަމައެފަދައިން، ތިމަންރަސްކަލާނގެ، ކޮންމެ ނަބީބޭކަލަކަށް އިންސީންނާއި، ޖިންނީންގެ ޝައިތާނުން އަދާވަތް ތެރިން ކަމުގައި ލެއްވީމެވެ. އޭގެ އެއްބަޔަކު އަނެއްބަޔަކަށް ހެއްލުންތެރި ކުރުމަށް މަތިއޮމާންކޮށްފައިވާ ބާތިލު ބަސްތަކުން ވަސްވާސްދީ އުޅެތެވެ. ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އިރާދަކުރެއްވިނަމަ، އެއުރެން އެކަންތަކެއް ނުކުރީހެވެ. ފަހެ، އެއުރެން ހަދާ ދޮގުތަކާއެކު، ކަލޭގެފާނު އެއުރެން ދޫކޮށްލައްވާށެވެ!","",""],["₆ سورة الأنعام","113","وَلِتَصۡغَىٰٓ إِلَيۡهِ أَفۡـِٔدَةُ ٱلَّذِينَ لَا يُؤۡمِنُونَ بِٱلۡأٓخِرَةِ وَلِيَرۡضَوۡهُ وَلِيَقۡتَرِفُواْ مَا هُم مُّقۡتَرِفُونَ ١١٣","ولتصغى إليه أفئدة الذين لا يؤمنون بالآخرة وليرضوه وليقترفوا ما هم مقترفون","އަދި (އެ ޝައިތާނުން ވަސްވާސްދީ އުޅެނީ) އާޚިރަތް ދުވަހަށް އީމާން ނުވާ މީހުންގެ ހިތްތައް އެ ވަސްވާހަށް ލެނބުމަށާއި، އެއުރެން އެކަމަށް ރުހި ގަބޫލު ވުމަށާއި، އެއުރެން އެ އަރައަރައިގަންނަ ފާފަތަކަށް އަރައިގަތުމަށްޓަކައެވެ.","",""],["₆ سورة الأنعام","114","أَفَغَيۡرَ ٱللَّهِ أَبۡتَغِي حَكَمٗا وَهُوَ ٱلَّذِيٓ أَنزَلَ إِلَيۡكُمُ ٱلۡكِتَٰبَ مُفَصَّلٗاۚ وَٱلَّذِينَ ءَاتَيۡنَٰهُمُ ٱلۡكِتَٰبَ يَعۡلَمُونَ أَنَّهُۥ مُنَزَّلٞ مِّن رَّبِّكَ بِٱلۡحَقِّۖ فَلَا تَكُونَنَّ مِنَ ٱلۡمُمۡتَرِينَ ١١٤","أفغير الله أبتغي حكما وهو الذي أنزل إليكم الكتاب مفصلا والذين آتيناهم الكتاب يعلمون أنه منزل من ربك بالحق فلا تكونن من الممترين","(ކަލޭގެފާނު ވިދާޅުވާށެވެ!) ހުކުމްކުރާ މީހަކު ކަމުގައި ﷲ ނޫންފަރާތެއް އަހުރެން އެދޭނެހެއްޔެވެ؟ އެކަލާނގެއީ، (ހައްގާއި ބާތިލު) ތަފްޞީލު ކޮށް ބަޔާންކުރައްވާފައިވާ ގޮތުގައި، ތިޔަބައިމީހުންނަށް ފޮތް ބާވައިލެއްވި ކަލާނގެއެވެ. އަދި އެއީ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ހައްގު ގޮތާއިގެން ބާވައިލެއްވި ފޮތެއްކަން، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ފޮތްދެއްވި މީހުން ދަނެތެވެ. ފަހެ، ޝައްކުކުރާ މީހުންގެ ތެރެއިން ކަލޭގެފާނު ވެވަޑައިނުގަންނަވާހުށިކަމެވެ!","",""],["₆ سورة الأنعام","115","وَتَمَّتۡ كَلِمَتُ رَبِّكَ صِدۡقٗا وَعَدۡلٗاۚ لَّا مُبَدِّلَ لِكَلِمَٰتِهِۦۚ وَهُوَ ٱلسَّمِيعُ ٱلۡعَلِيمُ ١١٥","وتمت كلمت ربك صدقا وعدلا لا مبدل لكلماته وهو السميع العليم","އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ކަލިމަފުޅު ތެދުވެރިކަމާއި، ޢަދުލުވެރި ކަމުގައި ފުރިހަމަވެއްޖެއެވެ. އެކަލާނގެ ކަލިމަފުޅުތައް ބަދަލުކުރެވޭނެ އެއްވެސް ފަރާތެއް ނުވެއެވެ. އަދި އެކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","116","وَإِن تُطِعۡ أَكۡثَرَ مَن فِي ٱلۡأَرۡضِ يُضِلُّوكَ عَن سَبِيلِ ٱللَّهِۚ إِن يَتَّبِعُونَ إِلَّا ٱلظَّنَّ وَإِنۡ هُمۡ إِلَّا يَخۡرُصُونَ ١١٦","وإن تطع أكثر من في الأرض يضلوك عن سبيل الله إن يتبعون إلا الظن وإن هم إلا يخرصون","އަދި ބިމުގައިވާ ގިނަ މީހުންނަށް ކަލޭގެފާނު ކިޔަމަންވެ ވަޑައިގެންފިނަމަ، އެއުރެން ﷲގެ މަގުން ކަލޭގެފާނު ފުރައްދައިފާނެތެވެ. އެއުރެން ހީއަކަށް ނޫނީ ތަބައެއް ނުވެތެވެ. އަދި ދޮގުހަދާ ބަޔަކު ކަމުގައި މެނުވީ، އެއުރެން ނުވެތެވެ.","",""],["₆ سورة الأنعام","117","إِنَّ رَبَّكَ هُوَ أَعۡلَمُ مَن يَضِلُّ عَن سَبِيلِهِۦۖ وَهُوَ أَعۡلَمُ بِٱلۡمُهۡتَدِينَ ١١٧","إن ربك هو أعلم من يضل عن سبيله وهو أعلم بالمهتدين","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ މަގު ދޫކޮށް، ފުރެދިގަންނަ މީހުން، އެންމެ ބޮޑަށް ދެނެވޮޑިގެންވަނީ، ހަމަ އެކަލާނގެއެވެ. އަދި ތެދުމަގު ލިބިގަންނަ މީހުން، އެންމެބޮޑަށް ދެނެވޮޑިގެންވަނީވެސް، ހަމަ އެކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","118","فَكُلُواْ مِمَّا ذُكِرَ ٱسۡمُ ٱللَّهِ عَلَيۡهِ إِن كُنتُم بِـَٔايَٰتِهِۦ مُؤۡمِنِينَ ١١٨","فكلوا مما ذكر اسم الله عليه إن كنتم بآياته مؤمنين","ތިޔަބައިމީހުން، އެކަލާނގެ އާޔަތްތަކަށް އީމާންވާ ކަމުގައިވަނީނަމަ، އެ އެއްޗެއްގެ މައްޗަށް ﷲގެ އިސްމުފުޅު ނަންގަނެފައިވާ ތަކެތިން (އެބަހީ: ﷲގެ އިސްމުފުޅު ނަންގަނެ ކަތިލާފައިވާ ތަކެތިން) ތިޔަބައިމީހުން ކައިއުޅޭށެވެ!","",""],["₆ سورة الأنعام","119","وَمَا لَكُمۡ أَلَّا تَأۡكُلُواْ مِمَّا ذُكِرَ ٱسۡمُ ٱللَّهِ عَلَيۡهِ وَقَدۡ فَصَّلَ لَكُم مَّا حَرَّمَ عَلَيۡكُمۡ إِلَّا مَا ٱضۡطُرِرۡتُمۡ إِلَيۡهِۗ وَإِنَّ كَثِيرٗا لَّيُضِلُّونَ بِأَهۡوَآئِهِم بِغَيۡرِ عِلۡمٍۚ إِنَّ رَبَّكَ هُوَ أَعۡلَمُ بِٱلۡمُعۡتَدِينَ ١١٩","وما لكم ألا تأكلوا مما ذكر اسم الله عليه وقد فصل لكم ما حرم عليكم إلا ما اضطررتم إليه وإن كثيرا ليضلون بأهوائهم بغير علم إن ربك هو أعلم بالمعتدين","ތިޔަބައިމީހުންގެ މައްޗަށް އެކަލާނގެ ހަރާމްކުރެއްވި ތަކެތި، ތަފްޞީލު ކޮށް ބަޔާންކޮށްދެއްވާފައިވާއިރު، އެއެއްޗެއްގެ މައްޗަށް ﷲގެ އިސްމުފުޅު ނަންގަނެ ކަތިލާ ތަކެތިން، ތިޔަބައިމީހުން ނުކާންވީ ކީއްވެގެންހެއްޔެވެ؟ ތިޔަބައިމީހުން އެ އެއްޗަކަށް ކޮންމެހެން ބޭނުންވެ، މަޖުބޫރުވެގެން ކާންޖެހިއްޖެ އެއްޗެއް މެނުވީއެވެ. ހަމަކަށަވަރުން، ވަރަށް ގިނަމީހުން ނުދެނެތިބެ، އެއުރެންގެ އަމިއްލަ އެދުންތަކުން (މީހުން) މަގުފުރައްދަތެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ހައްދުފަހަނަޅައިދާ މީހުން މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","120","وَذَرُواْ ظَٰهِرَ ٱلۡإِثۡمِ وَبَاطِنَهُۥٓۚ إِنَّ ٱلَّذِينَ يَكۡسِبُونَ ٱلۡإِثۡمَ سَيُجۡزَوۡنَ بِمَا كَانُواْ يَقۡتَرِفُونَ ١٢٠","وذروا ظاهر الإثم وباطنه إن الذين يكسبون الإثم سيجزون بما كانوا يقترفون","ތިޔަބައިމީހުން، ބޭރުފުށުގެ ފާފަޔާއި، އެތެރެފުށުގެ ފާފަދޫކޮށްލާށެވެ! ހަމަކަށަވަރުން، ފާފަތައް ހޯދައިގަންނަ މީހުންނަށް، އެއުރެން ކޮށްއުޅުނު ފާފަތަކުގެ ސަބަބުން ޖަޒާ ލިބޭނެތެވެ.","",""],["₆ سورة الأنعام","121","وَلَا تَأۡكُلُواْ مِمَّا لَمۡ يُذۡكَرِ ٱسۡمُ ٱللَّهِ عَلَيۡهِ وَإِنَّهُۥ لَفِسۡقٞۗ وَإِنَّ ٱلشَّيَٰطِينَ لَيُوحُونَ إِلَىٰٓ أَوۡلِيَآئِهِمۡ لِيُجَٰدِلُوكُمۡۖ وَإِنۡ أَطَعۡتُمُوهُمۡ إِنَّكُمۡ لَمُشۡرِكُونَ ١٢١","ولا تأكلوا مما لم يذكر اسم الله عليه وإنه لفسق وإن الشياطين ليوحون إلى أوليائهم ليجادلوكم وإن أطعتموهم إنكم لمشركون","(ކަތިލާހިނދު) އެ އެއްޗެއްގެ މައްޗަށް، ﷲގެ އިސްމުފުޅު ނަންނުގަންނަ އެއްޗަކުން ތިޔަބައިމީހުން ނުކާށެވެ! ހަމަކަށަވަރުން، އެތަކެތިން ކެއުމަކީ، އުރެދުމެއްކަން ކަށަވަރެވެ. އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނާ ޖަދަލުކުރުމަށް ޝައިތާނުން އެއުރެންގެ ވާގިވެރިންނަށް ވަސްވާސް ދޭނެއެވެ. ތިޔަބައިމީހުން، އެއުރެންނަށް ކިޔަމަންވެއްޖެނަމަ ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަކީވެސް، މުޝްރިކު ންކަން ކަށަވަރެވެ.","",""],["₆ سورة الأنعام","122","أَوَ مَن كَانَ مَيۡتٗا فَأَحۡيَيۡنَٰهُ وَجَعَلۡنَا لَهُۥ نُورٗا يَمۡشِي بِهِۦ فِي ٱلنَّاسِ كَمَن مَّثَلُهُۥ فِي ٱلظُّلُمَٰتِ لَيۡسَ بِخَارِجٖ مِّنۡهَاۚ كَذَٰلِكَ زُيِّنَ لِلۡكَٰفِرِينَ مَا كَانُواْ يَعۡمَلُونَ ١٢٢","أومن كان ميتا فأحييناه وجعلنا له نورا يمشي به في الناس كمن مثله في الظلمات ليس بخارج منها كذلك زين للكافرين ما كانوا يعملون","(ކާފިރުކަމުން) މަރުވެފައިވަނިކޮށް (ތެދުމަގު ދެއްކެވުމުން) ތިމަންރަސްކަލާނގެ އެމީހަކު ދިރުއްވައި، މީސްތަކުންގެ ތެރޭގައި އެނޫރެއްގެ އަލީގައި ހިނގާނޭ ނޫރެއްލެއްވި މީހަކާއި، އަނދިރީގެ ތެރޭގައި ނުނިކުމެހުންނަ މީހަކާ އެއްފަދަވާނޭ ހެއްޔެވެ؟ އެފަދައިން، ކާފިރުންނަށް އެއުރެންކޮށް އުޅުނު ޢަމަލުތައް ޒީނަތްތެރިކޮށް ދެއްވިއެވެ.","",""],["₆ سورة الأنعام","123","وَكَذَٰلِكَ جَعَلۡنَا فِي كُلِّ قَرۡيَةٍ أَكَٰبِرَ مُجۡرِمِيهَا لِيَمۡكُرُواْ فِيهَاۖ وَمَا يَمۡكُرُونَ إِلَّا بِأَنفُسِهِمۡ وَمَا يَشۡعُرُونَ ١٢٣","وكذلك جعلنا في كل قرية أكابر مجرميها ليمكروا فيها وما يمكرون إلا بأنفسهم وما يشعرون","އަދި ހަމައެފަދައިން، ކޮންމެރަށެއްގައި، އެރަށުގެ މުޖުރިމުންނަކީ، ބޮޑުން ކަމުގައި ލެއްވީމެވެ. (އެއީ) އެތާނގައި، އެއުރެން މަކަރުވެރި ރޭވުންތައް ރާވައި އުޅުމަށެވެ. އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް މެނުވީ، އެއުރެން މަކަރު ހަދާ ކަމުގައި ނުވެތެވެ. އަދި އެއުރެންނަކަށް އެކަމެއް ނުވިސްނެއެވެ.","",""],["₆ سورة الأنعام","124","وَإِذَا جَآءَتۡهُمۡ ءَايَةٞ قَالُواْ لَن نُّؤۡمِنَ حَتَّىٰ نُؤۡتَىٰ مِثۡلَ مَآ أُوتِيَ رُسُلُ ٱللَّهِۘ ٱللَّهُ أَعۡلَمُ حَيۡثُ يَجۡعَلُ رِسَالَتَهُۥۗ سَيُصِيبُ ٱلَّذِينَ أَجۡرَمُواْ صَغَارٌ عِندَ ٱللَّهِ وَعَذَابٞ شَدِيدُۢ بِمَا كَانُواْ يَمۡكُرُونَ ١٢٤","وإذا جاءتهم آية قالوا لن نؤمن حتى نؤتى مثل ما أوتي رسل الله الله أعلم حيث يجعل رسالته سيصيب الذين أجرموا صغار عند الله وعذاب شديد بما كانوا يمكرون","އެއުރެންގެ ގާތަށް އާޔަތެއް އަތުވެއްޖެނަމަ، އެއުރެން ބުނެތެވެ. ﷲގެ ރަސޫލުންނަށް ދެއްވިފަދަ ތަކެތި، ތިމަންމެންނަށްވެސް ދެއްވައިފުމަށް ދާނދެން، ތިމަންމެން އީމާނެއް ނުވާނޫއެވެ. ﷲ، އެކަލާނގެ ރަސޫލު ކަން ދެއްވާނެ މީހުން މޮޅަށް ދެނެވޮޑިގެންވެއެވެ. ފާފަވެރިވީ މީހުންނަށް، އެއުރެން މަކަރުހަދައި އުޅުނުކަމުގެ ސަބަބުން، ﷲގެ ހަޒުރަތުގައި ނިކަމެތިކަމާއި، ގަދަވެގެންވާ އަޒާބު އައިސްޖެހޭހުށްޓެވެ.","",""],["₆ سورة الأنعام","125","فَمَن يُرِدِ ٱللَّهُ أَن يَهۡدِيَهُۥ يَشۡرَحۡ صَدۡرَهُۥ لِلۡإِسۡلَٰمِۖ وَمَن يُرِدۡ أَن يُضِلَّهُۥ يَجۡعَلۡ صَدۡرَهُۥ ضَيِّقًا حَرَجٗا كَأَنَّمَا يَصَّعَّدُ فِي ٱلسَّمَآءِۚ كَذَٰلِكَ يَجۡعَلُ ٱللَّهُ ٱلرِّجۡسَ عَلَى ٱلَّذِينَ لَا يُؤۡمِنُونَ ١٢٥","فمن يرد الله أن يهديه يشرح صدره للإسلام ومن يرد أن يضله يجعل صدره ضيقا حرجا كأنما يصعد في السماء كذلك يجعل الله الرجس على الذين لا يؤمنون","ﷲގެ ތެދުމަގު ދެއްކެވުމަށް އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް، އިސްލާމް ދީނަށް އެމީހެއްގެ ހިތް ތަނަވަސްކޮށްދެއްވަތެވެ. އަދި އެކަލާނގެ މަގުފުރެއްދެވުމަށް އިރާދަކުރައްވާ މީހާ، އުޑާދިމާއަށް (މައްޗަށް) އަރައިގެންދާ މީހެކޭ އެއްފަދައިން އެކަލާނގެ އެމީހެއްގެ ހިތުގައި ދަތިކަމާއި، ނުތަނަވަސްކަން ލައްވަތެވެ. ހަމައެފަދައިން، އީމާން ނުވާ މީހުންގެ މައްޗަށް، ﷲގެ އަޒާބާއި ކޯފާ ލައްވަތެވެ.","",""],["₆ سورة الأنعام","126","وَهَٰذَا صِرَٰطُ رَبِّكَ مُسۡتَقِيمٗاۗ قَدۡ فَصَّلۡنَا ٱلۡأٓيَٰتِ لِقَوۡمٖ يَذَّكَّرُونَ ١٢٦","وهذا صراط ربك مستقيما قد فصلنا الآيات لقوم يذكرون","މިއީ ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ސީދާވެގެންވާ ތެދުމަގެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އާޔަތްތައް ތަފްޞީލު ކޮށް ބަޔާންކޮށްދެއްވީ ނަސޭހަތް ލިބިގަންނަ ބަޔަކަށެވެ.","",""],["₆ سورة الأنعام","127","۞لَهُمۡ دَارُ ٱلسَّلَٰمِ عِندَ رَبِّهِمۡۖ وَهُوَ وَلِيُّهُم بِمَا كَانُواْ يَعۡمَلُونَ ١٢٧","لهم دار السلام عند ربهم وهو وليهم بما كانوا يعملون","އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި، އަމާންކަމުގެ ގޮވަތި (ކަމުގައިވާ ސުވަރުގެ) އެއުރެންނަށް ހުށްޓެވެ. އަދި އެކަލާނގެއީ، އެއުރެން ކޮށްއުޅުނު ޢަމަލުތަކުގެ ސަބަބުން، އެއުރެންނަށް ނަސްރު ދެއްވާ، ވާގިދެއްވާ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","128","وَيَوۡمَ يَحۡشُرُهُمۡ جَمِيعٗا يَٰمَعۡشَرَ ٱلۡجِنِّ قَدِ ٱسۡتَكۡثَرۡتُم مِّنَ ٱلۡإِنسِۖ وَقَالَ أَوۡلِيَآؤُهُم مِّنَ ٱلۡإِنسِ رَبَّنَا ٱسۡتَمۡتَعَ بَعۡضُنَا بِبَعۡضٖ وَبَلَغۡنَآ أَجَلَنَا ٱلَّذِيٓ أَجَّلۡتَ لَنَاۚ قَالَ ٱلنَّارُ مَثۡوَىٰكُمۡ خَٰلِدِينَ فِيهَآ إِلَّا مَا شَآءَ ٱللَّهُۗ إِنَّ رَبَّكَ حَكِيمٌ عَلِيمٞ ١٢٨","ويوم يحشرهم جميعا يا معشر الجن قد استكثرتم من الإنس وقال أولياؤهم من الإنس ربنا استمتع بعضنا ببعض وبلغنا أجلنا الذي أجلت لنا قال النار مثواكم خالدين فيها إلا ما شاء الله إن ربك حكيم عليم","އެކަލާނގެ، އެއުރެން އެންމެން އެއްކުރައްވާ ދުވަސް ހަނދުމަކުރާށެވެ! (އެދުވަހުން، އެކަލާނގެ ވަހީކުރައްވާނެތެވެ.) އޭ ޖިންނީންގެ ޖަމާއަތްގެ މީހުންނޭވެ! ތިޔަބައިމީހުން އިންސީންގެ ވަރަށްގިނަ މީހުންނަށް މަގުއޮޅުވައިލީމުއެވެ. ދެން އިންސީންގެ ތެރެއިން އެއުރެންގެ އެކުވެރިން ދަންނަވާނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! އަޅަމެންގެ އެއްބަޔަކު އަނެއްބަޔެއްގެ ކިބައިން ފައިދާ ހޯދީމުއެވެ. އަދި އިބަރަސްކަލާނގެ، އަޅަމެންނަށް ކަނޑައަޅުއްވައިދެއްވައިފައިވާ އަޖަލަށް އަޅަމެން ފޯރައްޖައީމުއެވެ. އެކަލާނގެ ވަހީކުރައްވާނެތެވެ. ތިޔަބައިމީހުން ތިބޭނެ ތަނަކީ ނަރަކައެވެ. ﷲ އިރާދަކުރެއްވި ވަގުތަކަށް މެނުވީ، އެއުރެން އެތާނގައި ދެމިތިބެނިވި ގޮތުގައެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ޙަކީމްވަންތަ މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","129","وَكَذَٰلِكَ نُوَلِّي بَعۡضَ ٱلظَّـٰلِمِينَ بَعۡضَۢا بِمَا كَانُواْ يَكۡسِبُونَ ١٢٩","وكذلك نولي بعض الظالمين بعضا بما كانوا يكسبون","ހަމައެފަދައިން އެއުރެން ހޯދައިގަތް ކަމުގައިވީ ކަންތަކުގެ ސަބަބުން، ތިމަންރަސްކަލާނގެ އަނިޔާވެރިންގެ އެއްބަޔަކު އަނެއްބަޔަކާ މަތިކުރެއްވީމެވެ.","",""],["₆ سورة الأنعام","130","يَٰمَعۡشَرَ ٱلۡجِنِّ وَٱلۡإِنسِ أَلَمۡ يَأۡتِكُمۡ رُسُلٞ مِّنكُمۡ يَقُصُّونَ عَلَيۡكُمۡ ءَايَٰتِي وَيُنذِرُونَكُمۡ لِقَآءَ يَوۡمِكُمۡ هَٰذَاۚ قَالُواْ شَهِدۡنَا عَلَىٰٓ أَنفُسِنَاۖ وَغَرَّتۡهُمُ ٱلۡحَيَوٰةُ ٱلدُّنۡيَا وَشَهِدُواْ عَلَىٰٓ أَنفُسِهِمۡ أَنَّهُمۡ كَانُواْ كَٰفِرِينَ ١٣٠","يا معشر الجن والإنس ألم يأتكم رسل منكم يقصون عليكم آياتي وينذرونكم لقاء يومكم هذا قالوا شهدنا على أنفسنا وغرتهم الحياة الدنيا وشهدوا على أنفسهم أنهم كانوا كافرين","އޭ ޖިންނީންނާއި އިންސީންގެ ޖަމާއަތްގެ މީހުންނޭވެ! ތިޔަބައިމީހުންގެ ތެރެއިން ތިމަންރަސްކަލާނގެ އާޔަތްތަކުގެ ވާހަކަ ތިޔަބައިމީހުންނަށް ކިޔައިދެއްވައި، ތިޔަބައިމީހުންގެ މިދުވަހާ ބައްދަލުވާނެކަމުގެ އިންޒާރުކުރައްވާނެ ރަސޫލުންތަކެއް، ތިޔަބައިމީހުންގެ ގާތަށް ވަޑައިނުގަންނަވާހެއްޔެވެ؟ އެއުރެން ދަންނަވާނެތެވެ. އަޅަމެންގެ އަމިއްލަ ނަފްސުތަކުގެ މައްޗަށް އަޅަމެން ހެކިދީފީމުއެވެ. ދުނިޔޭގެ ދިރިއުޅުން އެއުރެން ހެއްލުންތެރި ކުރުވީއެވެ. އަދި އެއުރެން ކާފިރުން ކަމުގައި ވީކަމަށް އެއުރެންގެ އަމިއްލަ ނަފްސުތަކުގެ މައްޗަށް، އެއުރެން ހެކިދީފިއެވެ.","",""],["₆ سورة الأنعام","131","ذَٰلِكَ أَن لَّمۡ يَكُن رَّبُّكَ مُهۡلِكَ ٱلۡقُرَىٰ بِظُلۡمٖ وَأَهۡلُهَا غَٰفِلُونَ ١٣١","ذلك أن لم يكن ربك مهلك القرى بظلم وأهلها غافلون","ކަންހުރީ އެހެންނެވެ. ރަށްތަކުގެ އަހުލުވެރިން ޣާފިލު ވެފައި ތިއްބައި، އަނިޔާވެރިކަމުގެގޮތުން އެރަށްރަށް ހަލާކުކުރައްވާ ކަލަކު ކަމުގައި، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ނުވެއެވެ.","",""],["₆ سورة الأنعام","132","وَلِكُلّٖ دَرَجَٰتٞ مِّمَّا عَمِلُواْۚ وَمَا رَبُّكَ بِغَٰفِلٍ عَمَّا يَعۡمَلُونَ ١٣٢","ولكل درجات مما عملوا وما ربك بغافل عما يعملون","އަދި ކޮންމެ ބަޔަކަށްމެ އެބަޔަކު ކުޅަ ޢަމަލު ތަކާ އެއްގޮތަށް ދަރަޖަތަކެއް ހުށްޓެވެ. އަދި އެއުރެން ކުރާ ޢަމަލު ތަކާމެދު، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ޣާފިލުވެ ވޮޑިގެނެއްނުވެއެވެ.","",""],["₆ سورة الأنعام","133","وَرَبُّكَ ٱلۡغَنِيُّ ذُو ٱلرَّحۡمَةِۚ إِن يَشَأۡ يُذۡهِبۡكُمۡ وَيَسۡتَخۡلِفۡ مِنۢ بَعۡدِكُم مَّا يَشَآءُ كَمَآ أَنشَأَكُم مِّن ذُرِّيَّةِ قَوۡمٍ ءَاخَرِينَ ١٣٣","وربك الغني ذو الرحمة إن يشأ يذهبكم ويستخلف من بعدكم ما يشاء كما أنشأكم من ذرية قوم آخرين","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ފުދިވޮޑިގެންވާ، ރަހުމަތްގެ ވެރިރަސްކަލާނގެއެވެ. އެކަލާނގެ އިރާދަކުރައްވާނަމަ، ތިޔަބައިމީހުން ނެތިކުރައްވައި، ތިޔަބައިމީހުންގެ ފަހަށް، އެކަލާނގެ އިރާދަކުރައްވާ ބަޔަކު ފޮނުއްވައިފާހުށްޓެވެ. އެއީ ތިޔަބައިމީހުން، އެހެން ގައުމެއްގެ ދަރިކޮޅުން އުފެއްދެވި ފަދައިންނެވެ.","",""],["₆ سورة الأنعام","134","إِنَّ مَا تُوعَدُونَ لَأٓتٖۖ وَمَآ أَنتُم بِمُعۡجِزِينَ ١٣٤","إن ما توعدون لآت وما أنتم بمعجزين","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށް ވައުދުކުރައްވާ ކަންތަކަކީ، އަންނާނެކަން ކަށަވަރު ކަންތަކެވެ. އަދި ތިޔަބައިމީހުންނަކީ، (ތިމަންރަސްކަލާނގެ) ނުކުޅައްދައި، ރެކިގެންދާނޭ ބަޔަކު ކަމުގައި ނުވެއެވެ.","",""],["₆ سورة الأنعام","135","قُلۡ يَٰقَوۡمِ ٱعۡمَلُواْ عَلَىٰ مَكَانَتِكُمۡ إِنِّي عَامِلٞۖ فَسَوۡفَ تَعۡلَمُونَ مَن تَكُونُ لَهُۥ عَٰقِبَةُ ٱلدَّارِۚ إِنَّهُۥ لَا يُفۡلِحُ ٱلظَّـٰلِمُونَ ١٣٥","قل يا قوم اعملوا على مكانتكم إني عامل فسوف تعلمون من تكون له عاقبة الدار إنه لا يفلح الظالمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން، ތިޔަބައިމީހުންގެ ގޮތުގައި ތިބެގެން ޢަމަލު ކޮށް ބަލާށެވެ! ހަމަކަށަވަރުން، އަހުރެން، އަހުރެންގެ ގޮތުގައި ޢަމަލުކުރާނަމެވެ. އާޚިރަތް ދުވަހުން ތައުރީފު ލިބިގެންވާ ނިމުމެއް ލިބޭނީ، ކޮންބަޔަކަށްކަން ތިޔަބައިމީހުންނަށް ނިކަންހުރެ އެނގޭނެތެވެ. ހަމަކަށަވަރުން، އަނިޔާވެރިންނެއް ނުދިނޭނެތެވެ.","",""],["₆ سورة الأنعام","136","وَجَعَلُواْ لِلَّهِ مِمَّا ذَرَأَ مِنَ ٱلۡحَرۡثِ وَٱلۡأَنۡعَٰمِ نَصِيبٗا فَقَالُواْ هَٰذَا لِلَّهِ بِزَعۡمِهِمۡ وَهَٰذَا لِشُرَكَآئِنَاۖ فَمَا كَانَ لِشُرَكَآئِهِمۡ فَلَا يَصِلُ إِلَى ٱللَّهِۖ وَمَا كَانَ لِلَّهِ فَهُوَ يَصِلُ إِلَىٰ شُرَكَآئِهِمۡۗ سَآءَ مَا يَحۡكُمُونَ ١٣٦","وجعلوا لله مما ذرأ من الحرث والأنعام نصيبا فقالوا هذا لله بزعمهم وهذا لشركائنا فما كان لشركائهم فلا يصل إلى الله وما كان لله فهو يصل إلى شركائهم ساء ما يحكمون","އެ (ކާފިރުވި) މީހުން، ﷲއަށް އެކަލާނގެ އުފެއްދެވި ތަކެތީގެ ތެރެއިން، ދަނޑުގޮވާމާއި، ނަޢަމް ސޫފީން ބައެއް އެޅިއެވެ. އެއުރެންގެ ބާތިލު ހީއާއެއްގޮތަށް، އެއުރެންބުނީ، މިބައި މިއީ ﷲއަށެވެ. އަދި މިހިރަ ބައި އެއީ، ތިމަންމެންގެ ޝަރީކުންނަށެވެ. ފަހެ، އެއުރެންގެ ޝަރީކުންނަށްވީ ބައިގެ އެއްޗެއް، ﷲގެ ފަރާތަކަށް ނުލިބެއެވެ. ﷲއަށް އެޅިބައި، އެއުރެންގެ ޝަރީކުންނަށް ލިބެއެވެ. އެއުރެން ކުރާ ހުކުމް ހާދަހާ ނުބައިވެގެންވެއެވެ.","",""],["₆ سورة الأنعام","137","وَكَذَٰلِكَ زَيَّنَ لِكَثِيرٖ مِّنَ ٱلۡمُشۡرِكِينَ قَتۡلَ أَوۡلَٰدِهِمۡ شُرَكَآؤُهُمۡ لِيُرۡدُوهُمۡ وَلِيَلۡبِسُواْ عَلَيۡهِمۡ دِينَهُمۡۖ وَلَوۡ شَآءَ ٱللَّهُ مَا فَعَلُوهُۖ فَذَرۡهُمۡ وَمَا يَفۡتَرُونَ ١٣٧","وكذلك زين لكثير من المشركين قتل أولادهم شركاؤهم ليردوهم وليلبسوا عليهم دينهم ولو شاء الله ما فعلوه فذرهم وما يفترون","ހަމައެފަދައިން، މުޝްރިކުންގެ ގިނަ މީހުންނަށް އެއުރެންގެ ދަރިން މެރުމަށް، އެއުރެންގެ ޝަރީކުން، ޒީނަތްތެރިކޮށް ދެއްކިއެވެ. އެއީ އެއުރެން ހަލާކުގެ ތެރެޔަށް ފޮނުވުމަށެވެ. އަދި އެއުރެންނަށް އެއުރެންގެ ދީން އޮޅުވާލުމަށެވެ. ﷲ އިރާދަކުރެއްވިނަމަ، އެއުރެން އެކަމެއް ނުކުރީހެވެ. ފަހެ، ކަލޭގެފާނު އެއުރެން ހަދާ ދޮގުތަކާއެކު، އެއުރެން ދޫކޮށްލައްވާށެވެ!","",""],["₆ سورة الأنعام","138","وَقَالُواْ هَٰذِهِۦٓ أَنۡعَٰمٞ وَحَرۡثٌ حِجۡرٞ لَّا يَطۡعَمُهَآ إِلَّا مَن نَّشَآءُ بِزَعۡمِهِمۡ وَأَنۡعَٰمٌ حُرِّمَتۡ ظُهُورُهَا وَأَنۡعَٰمٞ لَّا يَذۡكُرُونَ ٱسۡمَ ٱللَّهِ عَلَيۡهَا ٱفۡتِرَآءً عَلَيۡهِۚ سَيَجۡزِيهِم بِمَا كَانُواْ يَفۡتَرُونَ ١٣٨","وقالوا هذه أنعام وحرث حجر لا يطعمها إلا من نشاء بزعمهم وأنعام حرمت ظهورها وأنعام لا يذكرون اسم الله عليها افتراء عليه سيجزيهم بما كانوا يفترون","އެއުރެން ބުނެފޫއެވެ. މިހިރީ، މަނާކޮށްފައިވާ ނަޢަމް ސޫފިތަކާއި ދަނޑުގޮވާންތަކެވެ. އެއުރެން ހީކުރާ ގޮތުގައި، އެއުރެން އެދޭ ބަޔަކު މެނުވީ، އެތަކެތި ކައިގެން ނުވާނެތެވެ. އަދި މިތިބީ އޭގެ ބުރިކަށިތައް ހަރާމް ކޮށްފައިވާ ނަޢަމް ސޫފިތަކެވެ. އަދި މިތިބީ، (ކަތިލާހިނދު) އޭގެ މައްޗަށް އެއުރެން، ﷲގެ އިސްމުފުޅު ނަންނުގަންނަ ނަޢަމް ސޫފިތަކެވެ. (މިހުރިހާ ކަމެއް އެއުރެން ކުރަނީ) އެކަލާނގެއަށް ދޮގުހެދުމުގެ ގޮތުންނެވެ. އެއުރެން ހަދާ އުޅުނު ދޮގުތަކުގެ ސަބަބުން، އެކަލާނގެ އެއުރެންނަށް ޖަޒާ ދެއްވާހުށްޓެވެ.","",""],["₆ سورة الأنعام","139","وَقَالُواْ مَا فِي بُطُونِ هَٰذِهِ ٱلۡأَنۡعَٰمِ خَالِصَةٞ لِّذُكُورِنَا وَمُحَرَّمٌ عَلَىٰٓ أَزۡوَٰجِنَاۖ وَإِن يَكُن مَّيۡتَةٗ فَهُمۡ فِيهِ شُرَكَآءُۚ سَيَجۡزِيهِمۡ وَصۡفَهُمۡۚ إِنَّهُۥ حَكِيمٌ عَلِيمٞ ١٣٩","وقالوا ما في بطون هذه الأنعام خالصة لذكورنا ومحرم على أزواجنا وإن يكن ميتة فهم فيه شركاء سيجزيهم وصفهم إنه حكيم عليم","އަދި އެއުރެން ބުނެފޫއެވެ. މި ނަޢަމް ސޫފިތަކުގެ ބަނޑުތެރޭގައިވާ ތަކެތި، ހަލާލު ވެގެންވަނީ، އަހުރެމެންކުރެ ފިރިހެނުންނަށެވެ. އަދި އެތަކެތި ވަނީ، އަހުރެމެންގެ އަންހެނުންގެ މައްޗަށް ހަރާމް ވެގެންނެވެ. އެތަކެތި މަރުވެފައިވާނަމަ، އެކެއުމުގައި އެންމެން ހަމަހަމައެވެ. އެއުރެން (އެތަކެއްޗަށް ހަލާލު ނުވަތަ ހަރާމްކަމުގެ) ސިފަދިނުމުގެ ސަބަބުން، އެއުރެންނަށް އެކަލާނގެ އުގޫބާތް ދެއްވާނެތެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ޙަކީމްވަންތަ މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","140","قَدۡ خَسِرَ ٱلَّذِينَ قَتَلُوٓاْ أَوۡلَٰدَهُمۡ سَفَهَۢا بِغَيۡرِ عِلۡمٖ وَحَرَّمُواْ مَا رَزَقَهُمُ ٱللَّهُ ٱفۡتِرَآءً عَلَى ٱللَّهِۚ قَدۡ ضَلُّواْ وَمَا كَانُواْ مُهۡتَدِينَ ١٤٠","قد خسر الذين قتلوا أولادهم سفها بغير علم وحرموا ما رزقهم الله افتراء على الله قد ضلوا وما كانوا مهتدين","އެއްވެސް އިލްމަކާނުލައި، ޖާހިލުކަމުން އެއުރެންގެ ދަރިން ގަތުލު ކޮށް، އެއުރެންނަށް ﷲ ދެއްވި ތަކެތި، ﷲއަށް ދޮގުހެދުމުގެ ގޮތުން، ހަރާމްކުޅަ މީހުން، ގެއްލި ހަލާކުވެއްޖެކަން ކަށަވަރެވެ. އެއުރެން މަގުފުރެދިއްޖެކަން ޔަގީނެވެ. އަދި އެއުރެންނަކީ، ތެދުމަގު ލިބިގެންވާ ބަޔަކު ކަމުގައިވެސް ނުވެއެވެ.","",""],["₆ سورة الأنعام","141","۞وَهُوَ ٱلَّذِيٓ أَنشَأَ جَنَّـٰتٖ مَّعۡرُوشَٰتٖ وَغَيۡرَ مَعۡرُوشَٰتٖ وَٱلنَّخۡلَ وَٱلزَّرۡعَ مُخۡتَلِفًا أُكُلُهُۥ وَٱلزَّيۡتُونَ وَٱلرُّمَّانَ مُتَشَٰبِهٗا وَغَيۡرَ مُتَشَٰبِهٖۚ كُلُواْ مِن ثَمَرِهِۦٓ إِذَآ أَثۡمَرَ وَءَاتُواْ حَقَّهُۥ يَوۡمَ حَصَادِهِۦۖ وَلَا تُسۡرِفُوٓاْۚ إِنَّهُۥ لَا يُحِبُّ ٱلۡمُسۡرِفِينَ ١٤١","وهو الذي أنشأ جنات معروشات وغير معروشات والنخل والزرع مختلفا أكله والزيتون والرمان متشابها وغير متشابه كلوا من ثمره إذا أثمر وآتوا حقه يوم حصاده ولا تسرفوا إنه لا يحب المسرفين","އެކަލާނގެއީ، ފެތުރޭ ވެޔޮތަކާއި، ވެޔޮނޫން ގަސްތަކުގެ ބަގީޗާތަކާއި، އޭގެ މޭވާއާއި، އޮށްޓަރު ތަފާތުވެގެންވާ ޙާލު، ކަދުރުރުކާއި، ގޮވާމާއި، އެއްވައްތަރު ވެގެންވާ ޙާލު ގައްޔާއި، އެއްވައްތަރުވެގެން ނުވާ ޙާލުގައި، ޒައިތޫންޏާއި، އަންނާރު އުފެއްދެވި ރަސްކަލާނގެއެވެ. އެ ގަސްތަކުން މޭވާ އަތުވެއްޖެނަމަ، އެ މޭވާއިން ތިޔަބައިމީހުން ކާށެވެ! އަދި ގޮވާންކަނޑާ ދުވަހަކުން، އޭގެ ޒަކާތް ދޭށެވެ! އަދި ތިޔަބައިމީހުން އިސްރާފު ނުކުރާށެވެ! އެހެނީ ހަމަކަށަވަރުން، އިސްރާފުކުރާ މީހުންދެކެ އެކަލާނގެ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["₆ سورة الأنعام","142","وَمِنَ ٱلۡأَنۡعَٰمِ حَمُولَةٗ وَفَرۡشٗاۚ كُلُواْ مِمَّا رَزَقَكُمُ ٱللَّهُ وَلَا تَتَّبِعُواْ خُطُوَٰتِ ٱلشَّيۡطَٰنِۚ إِنَّهُۥ لَكُمۡ عَدُوّٞ مُّبِينٞ ١٤٢","ومن الأنعام حمولة وفرشا كلوا مما رزقكم الله ولا تتبعوا خطوات الشيطان إنه لكم عدو مبين","އަދި ނަޢަމް ސޫފީގެ ތެރެއިން، އެއްޗެތި އުފުލާ އުސްތަކެއްޗާއި، އަދި (އެކަމަށް ކުޅަދާނަވެގެން ނުވާ) ބިމަށްތިރި ތަކެތި، އެކަލާނގެ އުފެއްދެވިއެވެ. ތިޔަބައިމީހުންނަށް ﷲ ދެއްވި ތަކެތިން ތިޔަބައިމީހުން ކާށެވެ! އަދި ޝައިތާނާގެ ފިޔަވަޅުތަކަށް، ތިޔަބައިމީހުން ތަބާ ނުވާށެވެ! ހަމަކަށަވަރުން، އެ ޝައިތާނާއަކީ، ތިޔަބައިމީހުންނަށް ކަނޑައެޅި ބަޔާންވެގެންހުރި އަދާވަތް ތެރިއެކެވެ.","",""],["₆ سورة الأنعام","143","ثَمَٰنِيَةَ أَزۡوَٰجٖۖ مِّنَ ٱلضَّأۡنِ ٱثۡنَيۡنِ وَمِنَ ٱلۡمَعۡزِ ٱثۡنَيۡنِۗ قُلۡ ءَآلذَّكَرَيۡنِ حَرَّمَ أَمِ ٱلۡأُنثَيَيۡنِ أَمَّا ٱشۡتَمَلَتۡ عَلَيۡهِ أَرۡحَامُ ٱلۡأُنثَيَيۡنِۖ نَبِّـُٔونِي بِعِلۡمٍ إِن كُنتُمۡ صَٰدِقِينَ ١٤٣","ثمانية أزواج من الضأن اثنين ومن المعز اثنين قل آلذكرين حرم أم الأنثيين أما اشتملت عليه أرحام الأنثيين نبئوني بعلم إن كنتم صادقين","އަންހެން ފިރިހެން، އަށެތި އުފައްދަވާފައިވެއެވެ. އެއީ ޟައުނު ބަކަރީގެ ދެޖޯޑާއި، މަޢިޒު ބަކަރީގެ ދެޖޯޑެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަލާނގެ ހަރާމްކުރައްވާފައިވަނީ، އެ ފިރިހެން ދޭތިހެއްޔެވެ؟ ނުވަތަ އެ އަންހެން ދޭތިހެއްޔެވެ؟ ނުވަތަ އެ އަންހެން ދޭތީގެ ރަޙިމު ގައިވާ ދަރިންހެއްޔެވެ؟ ތިޔަބައިމީހުންނަކީ، ތެދުވެރިން ކަމުގައިވާނަމަ، (ތިޔަބައިމީހުންނަށް ލިބިފައިވާ) އިލްމަކާއެކު، ތިމަންކަލޭގެފާނަށް ޚަބަރު ދީބަލާށެވެ!","",""],["₆ سورة الأنعام","144","وَمِنَ ٱلۡإِبِلِ ٱثۡنَيۡنِ وَمِنَ ٱلۡبَقَرِ ٱثۡنَيۡنِۗ قُلۡ ءَآلذَّكَرَيۡنِ حَرَّمَ أَمِ ٱلۡأُنثَيَيۡنِ أَمَّا ٱشۡتَمَلَتۡ عَلَيۡهِ أَرۡحَامُ ٱلۡأُنثَيَيۡنِۖ أَمۡ كُنتُمۡ شُهَدَآءَ إِذۡ وَصَّىٰكُمُ ٱللَّهُ بِهَٰذَاۚ فَمَنۡ أَظۡلَمُ مِمَّنِ ٱفۡتَرَىٰ عَلَى ٱللَّهِ كَذِبٗا لِّيُضِلَّ ٱلنَّاسَ بِغَيۡرِ عِلۡمٍۚ إِنَّ ٱللَّهَ لَا يَهۡدِي ٱلۡقَوۡمَ ٱلظَّـٰلِمِينَ ١٤٤","ومن الإبل اثنين ومن البقر اثنين قل آلذكرين حرم أم الأنثيين أما اشتملت عليه أرحام الأنثيين أم كنتم شهداء إذ وصاكم الله بهذا فمن أظلم ممن افترى على الله كذبا ليضل الناس بغير علم إن الله لا يهدي القوم الظالمين","އަދި ޖަމަލުގެ ދެ ޖޯޑާއި، ގެރީގެ ދެ ޖޯޑެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަލާނގެ ހަރާމްކުރެއްވީ އެ ފިރިހެން ދޭތިހެއްޔެވެ؟ ނުވަތަ އެ އަންހެން ދޭތިހެއްޔެވެ؟ ނުވަތަ އެއަންހެން ދޭތީގެ ރަޙިމު ގައިވާ ދަރިން ހެއްޔެވެ؟ ނުވަތަ ތިޔަބައިމީހުންނަށް، ﷲ މި ވަސިއްޔަތްކުރެއްވިއިރު، ހެކިންގެ ގޮތުގައި ތިޔަބައިމީހުން ޙާޒިރުުވެ ތިބީމުހެއްޔެވެ؟ އިލްމަކާނުލައި، މީސްތަކުން މަގުފުރެއްދުމަށްޓަކައި، ﷲއާމެދު، ހަދައިގެން ދޮގުބުނި މީހަކަށްވުރެ، އަނިޔާވެރިކަން ބޮޑުމީހަކީ ފަހެ ކާކުހެއްޔެވެ؟ ހަމަކަށަވަރުން، އަނިޔާވެރި ބަޔަކަށް ﷲ ތެދުމަގެއް ނުދަންކަވަތެވެ.","",""],["₆ سورة الأنعام","145","قُل لَّآ أَجِدُ فِي مَآ أُوحِيَ إِلَيَّ مُحَرَّمًا عَلَىٰ طَاعِمٖ يَطۡعَمُهُۥٓ إِلَّآ أَن يَكُونَ مَيۡتَةً أَوۡ دَمٗا مَّسۡفُوحًا أَوۡ لَحۡمَ خِنزِيرٖ فَإِنَّهُۥ رِجۡسٌ أَوۡ فِسۡقًا أُهِلَّ لِغَيۡرِ ٱللَّهِ بِهِۦۚ فَمَنِ ٱضۡطُرَّ غَيۡرَ بَاغٖ وَلَا عَادٖ فَإِنَّ رَبَّكَ غَفُورٞ رَّحِيمٞ ١٤٥","قل لا أجد في ما أوحي إلي محرما على طاعم يطعمه إلا أن يكون ميتة أو دما مسفوحا أو لحم خنزير فإنه رجس أو فسقا أهل لغير الله به فمن اضطر غير باغ ولا عاد فإن ربك غفور رحيم","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ކާ މީހަކަށް ކެއުން ހަރާމްކުރައްވާފައިވާ އެއްޗެއް، ތިމަންކަލޭގެފާނަށް އިއްވެވި ވަހީގެ ތެރޭގައި ވާތީ ދެކެވަޑައެއް ނުގަންނަވަމެވެ. އެ އެއްޗަކީ މަރުވެފައިވާ އެއްޗެއް ކަމުގައި، ނުވަތަ އޮހޮރޭ ލޭ ކަމުގައި، ނުވަތަ އޫރުމަސްކަމުގައި ވެއްޖެ އެއްޗެއް މެނުވީއެވެ. ހަމަކަށަވަރުން، އެ އޫރު މަހަކީ، ހަޑިމުޑުދާރު އެއްޗެކެވެ. ނުވަތަ ﷲ ނޫންފަރާތަކަށް ކަތިލާފައިވާ ފާސިގެއްޗެއްކަމުގައި ވެއްޖެ އެއްޗެއް މެނުވީއެވެ. (އެބަހީ: މިހަތަރު ބާވަތް ހަރާމް ވެގެންވެއެވެ.) ފަހެ، ނުކިޔަމަންތެރިވެ ދެކޮޅުވެރިވުމެއް އަދި ހައްދުފަހަނަޅައިދިޔުމެއް ނެތި، މަޖޫބުރުވެއްޖެ މީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₆ سورة الأنعام","146","وَعَلَى ٱلَّذِينَ هَادُواْ حَرَّمۡنَا كُلَّ ذِي ظُفُرٖۖ وَمِنَ ٱلۡبَقَرِ وَٱلۡغَنَمِ حَرَّمۡنَا عَلَيۡهِمۡ شُحُومَهُمَآ إِلَّا مَا حَمَلَتۡ ظُهُورُهُمَآ أَوِ ٱلۡحَوَايَآ أَوۡ مَا ٱخۡتَلَطَ بِعَظۡمٖۚ ذَٰلِكَ جَزَيۡنَٰهُم بِبَغۡيِهِمۡۖ وَإِنَّا لَصَٰدِقُونَ ١٤٦","وعلى الذين هادوا حرمنا كل ذي ظفر ومن البقر والغنم حرمنا عليهم شحومهما إلا ما حملت ظهورهما أو الحوايا أو ما اختلط بعظم ذلك جزيناهم ببغيهم وإنا لصادقون","ނިޔަފަތިހުރި ކޮންމެ ސޫތްޕެއް، ޔަހޫދީންގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ހަރާމްކުރެއްވީމެވެ. އަދި ގެރިއާއި، ބަކަރީން އޭގެ ބުރިކަށީގައިވާ ސަރުބީއާއި، އޭގެ ގޮހޮރުގައިވާ ސަރުބީއާއި، ކަށްޓާ އެކުވެފައިވާ ސަރުބީފިޔަވައި، އެދޭތީގެ ސަރުބީ، އެއުރެންގެ މައްޗަށް ހަރާމްކުރެއްވީމެވެ. އެގޮތުން، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ޖަޒާދެއްވީ، އެއުރެންގެ ދެކޮޅުވެރިކަމާއި، އަނިޔާވެރިކަމުގެ ސަބަބުންނެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެއީ، ތެދު ވަހީކުރައްވާ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["₆ سورة الأنعام","147","فَإِن كَذَّبُوكَ فَقُل رَّبُّكُمۡ ذُو رَحۡمَةٖ وَٰسِعَةٖ وَلَا يُرَدُّ بَأۡسُهُۥ عَنِ ٱلۡقَوۡمِ ٱلۡمُجۡرِمِينَ ١٤٧","فإن كذبوك فقل ربكم ذو رحمة واسعة ولا يرد بأسه عن القوم المجرمين","ފަހެ، އެއުރެން ކަލޭގެފާނު ދޮގުކޮށްފިނަމަ، ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއީ، ތަނަވަސްވެގެންވާ ރަހުމަތްގެ ވެރިރަސްކަލާނގެއެވެ. އެކަލާނގެ އަޒާބު (އަތުވެއްޖެނަމަ) ކުށްވެރިވީ މީހުންގެ ކިބައިން އަނބުރާ ރައްދުނުކުރައްވާ ހުށްޓެވެ.","",""],["₆ سورة الأنعام","148","سَيَقُولُ ٱلَّذِينَ أَشۡرَكُواْ لَوۡ شَآءَ ٱللَّهُ مَآ أَشۡرَكۡنَا وَلَآ ءَابَآؤُنَا وَلَا حَرَّمۡنَا مِن شَيۡءٖۚ كَذَٰلِكَ كَذَّبَ ٱلَّذِينَ مِن قَبۡلِهِمۡ حَتَّىٰ ذَاقُواْ بَأۡسَنَاۗ قُلۡ هَلۡ عِندَكُم مِّنۡ عِلۡمٖ فَتُخۡرِجُوهُ لَنَآۖ إِن تَتَّبِعُونَ إِلَّا ٱلظَّنَّ وَإِنۡ أَنتُمۡ إِلَّا تَخۡرُصُونَ ١٤٨","سيقول الذين أشركوا لو شاء الله ما أشركنا ولا آباؤنا ولا حرمنا من شيء كذلك كذب الذين من قبلهم حتى ذاقوا بأسنا قل هل عندكم من علم فتخرجوه لنا إن تتبعون إلا الظن وإن أنتم إلا تخرصون","ޝަރީކުކުޅަ މީހުން ބުނާނެތެވެ. ﷲ އިރާދަކުރެއްވިނަމަ ތިމަންމެން، އަދި ތިމަންމެންގެ ކާބަފައިންވެސް، ޝަރީކެއް ނުކުޅައީހެވެ. އަދި ތިމަންމެން އެއްވެސް އެއްޗެއް ހަރާމް ކޮށެއްވެސް ނުހެދީމުހެވެ. ހަމައެފަދައިން، އެއުރެންގެ ކުރީގެ މީހުން، ތިމަންރަސްކަލާނގެ އަޒާބުގެ ރަހަ ލިބިއްޖައުމަށްދާނދެން (ރަސޫލުން) ދޮގުކުޅައޫވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން، އަހުރެމެންނަށް ނެރެދައްކައިދޭނޭ އެއްވެސް އިލްމެއް، ތިޔަބައިމީހުންގެ ކިބައިގައި ވޭހެއްޔެވެ؟ ތިޔަބައިމީހުން ތަބާ ވަނީ، ހީއަކަށް ކަމުގައި މެނުވީ ނުވެއެވެ. އަދި ތިޔަބައިމީހުން ދޮގުހަދާ ބަޔަކު ކަމުގައި މެނުވީ ނުވެއެވެ.","",""],["₆ سورة الأنعام","149","قُلۡ فَلِلَّهِ ٱلۡحُجَّةُ ٱلۡبَٰلِغَةُۖ فَلَوۡ شَآءَ لَهَدَىٰكُمۡ أَجۡمَعِينَ ١٤٩","قل فلله الحجة البالغة فلو شاء لهداكم أجمعين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ފަހެ، އެންމެ ފުރިހަމަ ހުއްޖަތް ވަނީ ﷲއަށެވެ. ފަހެ، އެކަލާނގެ އިރާދަކުރެއްވިނަމަ، ތިޔަބައިމީހުން އެންމެންނަށް، ތެދުމަގު ދައްކަވައިފީސްކަން ކަށަވަރެވެ.","",""],["₆ سورة الأنعام","150","قُلۡ هَلُمَّ شُهَدَآءَكُمُ ٱلَّذِينَ يَشۡهَدُونَ أَنَّ ٱللَّهَ حَرَّمَ هَٰذَاۖ فَإِن شَهِدُواْ فَلَا تَشۡهَدۡ مَعَهُمۡۚ وَلَا تَتَّبِعۡ أَهۡوَآءَ ٱلَّذِينَ كَذَّبُواْ بِـَٔايَٰتِنَا وَٱلَّذِينَ لَا يُؤۡمِنُونَ بِٱلۡأٓخِرَةِ وَهُم بِرَبِّهِمۡ يَعۡدِلُونَ ١٥٠","قل هلم شهداءكم الذين يشهدون أن الله حرم هذا فإن شهدوا فلا تشهد معهم ولا تتبع أهواء الذين كذبوا بآياتنا والذين لا يؤمنون بالآخرة وهم بربهم يعدلون","ކަލޭގެފާނު ވިދާޅުވާށެވެ. ﷲ މި ތަކެތި ހަރާމްކުރެއްވިކަމަށް ހެކިވާނެ ހެކިން ތިޔަބައިމީހުން ގެންނާށެވެ! ދެން އެއުރެން، ހެކިދިން ނަމަވެސް، ކަލޭގެފާނު އެއުރެންނާ އެކުގައި ހެކިވެވަޑައިނުގަންނަވާށެވެ! އަދި އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް، ޝަރީކުކުރާ ޙާލު، ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކޮށް، އާޚިރަތް ދުވަހަށް އީމާން ނުވާ މީހުން، ހިތް އެދޭ ގޮތްތަކަށް ކަލޭގެފާނު ތަބާ ވެވަޑައިނުގަންނަވާށެވެ!","",""],["₆ سورة الأنعام","151","۞قُلۡ تَعَالَوۡاْ أَتۡلُ مَا حَرَّمَ رَبُّكُمۡ عَلَيۡكُمۡۖ أَلَّا تُشۡرِكُواْ بِهِۦ شَيۡـٔٗاۖ وَبِٱلۡوَٰلِدَيۡنِ إِحۡسَٰنٗاۖ وَلَا تَقۡتُلُوٓاْ أَوۡلَٰدَكُم مِّنۡ إِمۡلَٰقٖ نَّحۡنُ نَرۡزُقُكُمۡ وَإِيَّاهُمۡۖ وَلَا تَقۡرَبُواْ ٱلۡفَوَٰحِشَ مَا ظَهَرَ مِنۡهَا وَمَا بَطَنَۖ وَلَا تَقۡتُلُواْ ٱلنَّفۡسَ ٱلَّتِي حَرَّمَ ٱللَّهُ إِلَّا بِٱلۡحَقِّۚ ذَٰلِكُمۡ وَصَّىٰكُم بِهِۦ لَعَلَّكُمۡ تَعۡقِلُونَ ١٥١","قل تعالوا أتل ما حرم ربكم عليكم ألا تشركوا به شيئا وبالوالدين إحسانا ولا تقتلوا أولادكم من إملاق نحن نرزقكم وإياهم ولا تقربوا الفواحش ما ظهر منها وما بطن ولا تقتلوا النفس التي حرم الله إلا بالحق ذلكم وصاكم به لعلكم تعقلون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން އަންނާށެވެ! ތިޔަބައިމީހުންގެ މައްޗަށް، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަރާމްކުރެއްވި ކަންތައް ކިޔައިދެއްވާ ހުށީމެވެ. ތިޔަބައިމީހުން، އެކަލާނގެއަށް އެއްވެސް އެއްޗެއް ޝަރީކު ނުކުރާށެވެ! އަދި މައިންބަފައިންނަށް ހެޔޮކޮށް ހިތާށެވެ! އަދި ފަގީރުކަމުގެ ސަބަބުން ތިޔަބައިމީހުން ދަރިން ނުމަރާށެވެ! ތިޔަބައިމީހުންނަށާއި، އެ ދަރިންނަށް ރިޒްގު ދެއްވަނީ، ތިމަންރަސްކަލާނގެއެވެ. އަދި ފާޙީޝް ކަންތައްތަކާ ތިޔަބައިމީހުން ކައިރި ނުވާށެވެ! އޭގެތެރެއިން ފާޅުވެގެންވާ ކަންތަކާއި، ވަންހަނާ ވެގެންވާ ކަންތަކެވެ. އަދި ﷲ ހުރުމަތް ތެރި ކުރައްވާފައިވާ ނަފްސެއް، ހައްގަކާ ނުލައި ނުމަރާށެވެ! އެކަންތައްތަކާމެދު، އެކަލާނގެ ތިޔަބައިމީހުންނަށް ވަސިއްޔަތްކުރެއްވީ، ތިޔަބައިމީހުން ވިސްނުމަށްޓަކައެވެ.","",""],["₆ سورة الأنعام","152","وَلَا تَقۡرَبُواْ مَالَ ٱلۡيَتِيمِ إِلَّا بِٱلَّتِي هِيَ أَحۡسَنُ حَتَّىٰ يَبۡلُغَ أَشُدَّهُۥۚ وَأَوۡفُواْ ٱلۡكَيۡلَ وَٱلۡمِيزَانَ بِٱلۡقِسۡطِۖ لَا نُكَلِّفُ نَفۡسًا إِلَّا وُسۡعَهَاۖ وَإِذَا قُلۡتُمۡ فَٱعۡدِلُواْ وَلَوۡ كَانَ ذَا قُرۡبَىٰۖ وَبِعَهۡدِ ٱللَّهِ أَوۡفُواْۚ ذَٰلِكُمۡ وَصَّىٰكُم بِهِۦ لَعَلَّكُمۡ تَذَكَّرُونَ ١٥٢","ولا تقربوا مال اليتيم إلا بالتي هي أحسن حتى يبلغ أشده وأوفوا الكيل والميزان بالقسط لا نكلف نفسا إلا وسعها وإذا قلتم فاعدلوا ولو كان ذا قربى وبعهد الله أوفوا ذلكم وصاكم به لعلكم تذكرون","ރަނގަޅުގޮތުން މެނުވީ، ތިޔަބައިމީހުން ޔަތީމުންގެ މުދަލާ ގާތްނުވާށެވެ! އެކުދިން ބޮޑުވެ ތަޞައްރަފު ފުދިއްޖައުމަށް ދާނދެނެވެ. އަދި ތިޔަބައިމީހުން، މިނުމާއި، ކިރުން އިންޞާފުވެރި ގޮތުން ފުރިހަމަ ކުރާށެވެ! ތިމަންރަސްކަލާނގެ އެއްވެސް ނަފްސަކަށް، އެ ނަފްސަކަށް ކުޅަދާނަ ވެގެންވާ މިންވަރަށް މެނުވީ، ތަކުލީފެއް ނުޖައްސަވަމެވެ. އަދި ތިޔަބައިމީހުން ބަސްބުނާނަމަ، ގާތްތިމާގެ މީހަކާ މެދުގައި ނަމަވެސް، ޢަދުލަށް (ތެދަށް) ބުނާށެވެ! އަދި ﷲގެ އަހުދުތައް ތިޔަބައިމީހުން ފުއްދާށެވެ! އެކަންތައްތަކަށް، ތިޔަބައިމީހުންނަށް ވަސިއްޔަތްކުރެއްވީ ތިޔަބައިމީހުން ހަނދުމަކުރުމަށްޓަކައެވެ.","",""],["₆ سورة الأنعام","153","وَأَنَّ هَٰذَا صِرَٰطِي مُسۡتَقِيمٗا فَٱتَّبِعُوهُۖ وَلَا تَتَّبِعُواْ ٱلسُّبُلَ فَتَفَرَّقَ بِكُمۡ عَن سَبِيلِهِۦۚ ذَٰلِكُمۡ وَصَّىٰكُم بِهِۦ لَعَلَّكُمۡ تَتَّقُونَ ١٥٣","وأن هذا صراطي مستقيما فاتبعوه ولا تتبعوا السبل فتفرق بكم عن سبيله ذلكم وصاكم به لعلكم تتقون","އަދި މިއީ ތިމަންރަސްކަލާނގެ ސީދާވެގެންވާ ތެދުމަގެވެ. ފަހެ، އެ މަގަށް ތިޔަބައިމީހުން ތަބާ ވާށެވެ! (އެނޫން) މަގުމަގަށް ތިޔަބައިމީހުން ތަބާ ނުވާށެވެ! (އޭރުން) އެކަލާނގެ މަގުން ތިޔަބައިމީހުން ވަކިވަކިވެގެން ހިނގައިދާނެތެވެ. މިކަންތައްތަކަށް، ތިޔަބައިމީހުންނަށް އެކަލާނގެ ވަސިއްޔަތްކުރެއްވީ، ތިޔަބައިމީހުން ތަގުވާވެރިވުމަށްޓަކައެވެ.","",""],["₆ سورة الأنعام","154","ثُمَّ ءَاتَيۡنَا مُوسَى ٱلۡكِتَٰبَ تَمَامًا عَلَى ٱلَّذِيٓ أَحۡسَنَ وَتَفۡصِيلٗا لِّكُلِّ شَيۡءٖ وَهُدٗى وَرَحۡمَةٗ لَّعَلَّهُم بِلِقَآءِ رَبِّهِمۡ يُؤۡمِنُونَ ١٥٤","ثم آتينا موسى الكتاب تماما على الذي أحسن وتفصيلا لكل شيء وهدى ورحمة لعلهم بلقاء ربهم يؤمنون","ދެން ހެޔޮޢަމަލުކުޅަ މީހާއަށް (ނިއުމަތް) ފުރިހަމަކޮށް ދެއްވުމަށާއި، ކޮންމެ ކަމެއް ތަފްޞީލު ކޮށް ބަޔާންކޮށްދެއްވުމަށާއި، ހިދާޔަތެއް ކަމުގައްޔާއި، ރަހުމަތެއް ކަމުގައި، ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް ފޮތް ދެއްވީމެވެ. (އެއީ) އެއުރެންގެ ވެރިރަސްކަލާނގެއާ ބައްދަލުވާނެކަމަށް، އެއުރެން އީމާން ވުމަށްޓަކައެވެ.","",""],["₆ سورة الأنعام","155","وَهَٰذَا كِتَٰبٌ أَنزَلۡنَٰهُ مُبَارَكٞ فَٱتَّبِعُوهُ وَٱتَّقُواْ لَعَلَّكُمۡ تُرۡحَمُونَ ١٥٥","وهذا كتاب أنزلناه مبارك فاتبعوه واتقوا لعلكم ترحمون","މި ގުރްއާނަކީ، ތިމަންރަސްކަލާނގެ ބާވައިލެއްވި، ފޮތެކެވެ. ބަރަކާތްތެރި ފޮތެކެވެ. ފަހެ، ތިޔަބައިމީހުން، އެފޮތަށް ތަބާ ވާށެވެ! އަދި ތިޔަބައިމީހުން ތަގުވާވެރިވާށެވެ! (އެއީ) ތިޔަބައިމީހުންނަށް ރަހުމަތް ލެއްވުމަށްޓަކައެވެ.","",""],["₆ سورة الأنعام","156","أَن تَقُولُوٓاْ إِنَّمَآ أُنزِلَ ٱلۡكِتَٰبُ عَلَىٰ طَآئِفَتَيۡنِ مِن قَبۡلِنَا وَإِن كُنَّا عَن دِرَاسَتِهِمۡ لَغَٰفِلِينَ ١٥٦","أن تقولوا إنما أنزل الكتاب على طائفتين من قبلنا وإن كنا عن دراستهم لغافلين","ފޮތް ބާވައިލެއްވިކަން ކަށަވަރީ، ތިމަންމެންގެ ކުރީގައިވާ ދެބަޔެއްގެ މައްޗަށޭ، އަދި ތިމަންމެން، ހަމަކަށަވަރުންވެސް ތިބީ، އެއުރެން ކުޅަ ދިރާސާއާމެދު ޣާފިލު ވެގެންނޭ، ތިޔަބައިމީހުން ބުނެފާނެތީއެވެ.","",""],["₆ سورة الأنعام","157","أَوۡ تَقُولُواْ لَوۡ أَنَّآ أُنزِلَ عَلَيۡنَا ٱلۡكِتَٰبُ لَكُنَّآ أَهۡدَىٰ مِنۡهُمۡۚ فَقَدۡ جَآءَكُم بَيِّنَةٞ مِّن رَّبِّكُمۡ وَهُدٗى وَرَحۡمَةٞۚ فَمَنۡ أَظۡلَمُ مِمَّن كَذَّبَ بِـَٔايَٰتِ ٱللَّهِ وَصَدَفَ عَنۡهَاۗ سَنَجۡزِي ٱلَّذِينَ يَصۡدِفُونَ عَنۡ ءَايَٰتِنَا سُوٓءَ ٱلۡعَذَابِ بِمَا كَانُواْ يَصۡدِفُونَ ١٥٧","أو تقولوا لو أنا أنزل علينا الكتاب لكنا أهدى منهم فقد جاءكم بينة من ربكم وهدى ورحمة فمن أظلم ممن كذب بآيات الله وصدف عنها سنجزي الذين يصدفون عن آياتنا سوء العذاب بما كانوا يصدفون","ނުވަތަ ތިމަންމެންގެ މައްޗަށް ފޮތް ބާވައިލެއްވިނަމަ، އެއުރެންނަށްވުރެ، ތިމަންމެން ތެދުމަގު ލިބިގަތުން މާބޮޑުވީހޭ ބުނެފާނެތީއެވެ. ފަހެ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން، ސާފު ހެތްކަކާއި، ތެދުމަގަކާއި، ރަހުމަތެއް، ތިޔަބައިމީހުންގެ ގާތަށް އަތުވެއްޖެކަން ކަށަވަރެވެ. ﷲގެ އާޔަތްތައް ދޮގުކޮށް، އެ އާޔަތްތަކަށް ފުރަގަސްދީފި މީހަކަށްވުރެ، އަނިޔާވެރިކަންބޮޑީ ފަހެ، ކާކުހެއްޔެވެ؟ ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް ފުރަގަސްދޭ މީހުންނަށް، އެއުރެން އެ އާޔަތްތަކަށް ފުރަގަސް ދިނުމުގެ ސަބަބުން، ތިމަންރަސްކަލާނގެ ގަދަ އަޒާބުން، ޖަޒާދެއްވާހުށީމެވެ.","",""],["₆ سورة الأنعام","158","هَلۡ يَنظُرُونَ إِلَّآ أَن تَأۡتِيَهُمُ ٱلۡمَلَـٰٓئِكَةُ أَوۡ يَأۡتِيَ رَبُّكَ أَوۡ يَأۡتِيَ بَعۡضُ ءَايَٰتِ رَبِّكَۗ يَوۡمَ يَأۡتِي بَعۡضُ ءَايَٰتِ رَبِّكَ لَا يَنفَعُ نَفۡسًا إِيمَٰنُهَا لَمۡ تَكُنۡ ءَامَنَتۡ مِن قَبۡلُ أَوۡ كَسَبَتۡ فِيٓ إِيمَٰنِهَا خَيۡرٗاۗ قُلِ ٱنتَظِرُوٓاْ إِنَّا مُنتَظِرُونَ ١٥٨","هل ينظرون إلا أن تأتيهم الملائكة أو يأتي ربك أو يأتي بعض آيات ربك يوم يأتي بعض آيات ربك لا ينفع نفسا إيمانها لم تكن آمنت من قبل أو كسبت في إيمانها خيرا قل انتظروا إنا منتظرون","އެއުރެންގެ ގާތަށް، މަލާއިކަތުން ވަޑައިގަތުމަށް މެނުވީ، ނުވަތަ ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ވަޑައިގަތުމަށް މެނުވީ، ނުވަތަ ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އާޔަތްތަކުގެ ތެރެއިން ބައެއް އާޔަތް އައުމަށް މެނުވީ، އެއުރެން އިންތިޒާރުކުރޭހެއްޔެވެ؟ ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، ބައެއް އާޔަތް (އެބަހީ: ގިޔާމަތްގެ އަލާމަތްތައް) އަންނަ ދުވަހު، އޭގެކުރިން އީމާން ވެފައި ނުވާނަމަ، ނުވަތަ އީމާންވެ ހެޔޮޢަމަލު ކޮށްފައި ނުވާނަމަ، އެއްވެސް ނަފްސަކަށް އެ ނަފްސެއްގެ އީމާނަކުން މަންފާއެއް ނުކުރާނެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން އިންތިޒާރުކުރާށެވެ! ހަމަކަށަވަރުން، ތިމަންމެންވެސް އިންތިޒާރުކުރާނޫއެވެ.","",""],["₆ سورة الأنعام","159","إِنَّ ٱلَّذِينَ فَرَّقُواْ دِينَهُمۡ وَكَانُواْ شِيَعٗا لَّسۡتَ مِنۡهُمۡ فِي شَيۡءٍۚ إِنَّمَآ أَمۡرُهُمۡ إِلَى ٱللَّهِ ثُمَّ يُنَبِّئُهُم بِمَا كَانُواْ يَفۡعَلُونَ ١٥٩","إن الذين فرقوا دينهم وكانوا شيعا لست منهم في شيء إنما أمرهم إلى الله ثم ينبئهم بما كانوا يفعلون","ހަމަކަށަވަރުން، އެއުރެންގެ ދީން ބައިބައިކޮށް، ބައިތަކެއް ކަމުގައިވީ މީހުންގެ ތެރެއިން، އެއްވެސް ކަމެއްގައި، ކަލޭގެފާނު ނުވަމުއެވެ. އެއުރެންގެ ކަންތައް އޮންނާނެކަން ކަށަވަރީ، ﷲގެ ހަޒުރަތަށެވެ. ދެން އެއުރެން ކޮށްއުޅުނު ކަންތަކުގެ ވާހަކައިން، އެކަލާނގެ، އެއުރެންނަށް ޚަބަރު އަންގަވާނެތެވެ.","",""],["₆ سورة الأنعام","160","مَن جَآءَ بِٱلۡحَسَنَةِ فَلَهُۥ عَشۡرُ أَمۡثَالِهَاۖ وَمَن جَآءَ بِٱلسَّيِّئَةِ فَلَا يُجۡزَىٰٓ إِلَّا مِثۡلَهَا وَهُمۡ لَا يُظۡلَمُونَ ١٦٠","من جاء بالحسنة فله عشر أمثالها ومن جاء بالسيئة فلا يجزى إلا مثلها وهم لا يظلمون","ހެޔޮކަމެއް ކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް އެފަދަ ދިހަ ހެޔޮކަމުގެ ސަވާބު ހުށްޓެވެ. އަދި ނުބައިކަމެއް ކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެފަދަ ކަމެއްގެ ޖަޒާ މެނުވީ، އެމީހަކަށް ނުލިބޭހުށްޓެވެ. އަދި އެއުރެންނަކަށް ބޭއިންސާފެއް ނުކުރައްވާހުށްޓެވެ.","",""],["₆ سورة الأنعام","161","قُلۡ إِنَّنِي هَدَىٰنِي رَبِّيٓ إِلَىٰ صِرَٰطٖ مُّسۡتَقِيمٖ دِينٗا قِيَمٗا مِّلَّةَ إِبۡرَٰهِيمَ حَنِيفٗاۚ وَمَا كَانَ مِنَ ٱلۡمُشۡرِكِينَ ١٦١","قل إنني هداني ربي إلى صراط مستقيم دينا قيما ملة إبراهيم حنيفا وما كان من المشركين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ތިމަންގެ ވެރިރަސްކަލާނގެ، ސީދާވެގެންވާ ތެދުމަގަށް ތިމަންކަލޭގެފާނަށް މަގު ދެއްކެވިއެވެ. އެއީ ސީދާވެގެންވާ ދީނެވެ. އެއީ ބާތިލުގެ މަގުން އެއްކިބާވެ، ހައްގުގެ މަގަށް ތަބާ ވެގެންވާ އިބްރާހީމްގެފާނުގެ ދީނެވެ. އަދި މުޝްރިކުންގެ ތެރެއިން އެކަލޭގެފާނު ނުވެއެވެ.","",""],["₆ سورة الأنعام","162","قُلۡ إِنَّ صَلَاتِي وَنُسُكِي وَمَحۡيَايَ وَمَمَاتِي لِلَّهِ رَبِّ ٱلۡعَٰلَمِينَ ١٦٢","قل إن صلاتي ونسكي ومحياي ومماتي لله رب العالمين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުންގެ ނަމާދާއި، ތިމަންކަލޭގެފާނުގެ (އެހެނިހެން) އަޅުކަންތަކާއި، ތިމަންކަލޭގެފާނުގެ ދިރިހުންނެވުމާއި، ތިމަންކަލޭގެފާނުގެ އަވަހާރަވުންވަނީ، އާލަމްތަކުގެ ވެރި ﷲއަށެވެ.","",""],["₆ سورة الأنعام","163","لَا شَرِيكَ لَهُۥۖ وَبِذَٰلِكَ أُمِرۡتُ وَأَنَا۠ أَوَّلُ ٱلۡمُسۡلِمِينَ ١٦٣","لا شريك له وبذلك أمرت وأنا أول المسلمين","އެކަލާނގެއަށް އެއްވެސް ޝަރީކަކު ނުވެއެވެ. އަދި ތިމަންކަލޭގެފާނަށް އަމުރު ކުރައްވާފައިވަނީ އެގޮތަށެވެ. އަދި ތިމަންކަލޭގެފާނީ (މި އުއްމަތްގެ) މުސްލިމު ންކުރެ، އެންމެ ފުރަތަމަ މީހާއެވެ.","",""],["₆ سورة الأنعام","164","قُلۡ أَغَيۡرَ ٱللَّهِ أَبۡغِي رَبّٗا وَهُوَ رَبُّ كُلِّ شَيۡءٖۚ وَلَا تَكۡسِبُ كُلُّ نَفۡسٍ إِلَّا عَلَيۡهَاۚ وَلَا تَزِرُ وَازِرَةٞ وِزۡرَ أُخۡرَىٰۚ ثُمَّ إِلَىٰ رَبِّكُم مَّرۡجِعُكُمۡ فَيُنَبِّئُكُم بِمَا كُنتُمۡ فِيهِ تَخۡتَلِفُونَ ١٦٤","قل أغير الله أبغي ربا وهو رب كل شيء ولا تكسب كل نفس إلا عليها ولا تزر وازرة وزر أخرى ثم إلى ربكم مرجعكم فينبئكم بما كنتم فيه تختلفون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަލާނގެއީ، ހުރިހާ ތަކެއްޗެއްގެ ވެރިރަސްކަލާނގެ ކަމުގައިވާ ޙާލު، ކަލަކު ކަމުގައި، ﷲ ފިޔަވައި އެހެން ފަރާތެއް ތިމަންކަލޭގެފާނު އެދޭނޭ ހެއްޔެވެ؟ ކޮންމެ ނަފްސެއްމެ، އެ ނަފްސެއް ހޯދައިގަތް ކަމެއް މެނުވީ، އެ ނަފްސެއްގެ މައްޗަކަށް ނުވެއެވެ. އަދި ފާފަވެރި އެއްވެސް ނަފްސެއް، އެހެން ނަފްސެއްގެ ފާފައެއް ނުއުފުލާނެތެވެ. ދެން ތިޔަބައިމީހުން އެނބުރި ރުޖޫއަ ވުންހުރީ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށެވެ. އޭރުން، ތިޔަބައިމީހުން، އެކަންކަމާމެދު ޚިލާފުވެ އުޅުނު ކަންތަކުގެ ޚަބަރު ތިޔަބައިމީހުންނަށް، އެކަލާނގެ އަންގަވާނެތެވެ.","",""],["₆ سورة الأنعام","165","وَهُوَ ٱلَّذِي جَعَلَكُمۡ خَلَـٰٓئِفَ ٱلۡأَرۡضِ وَرَفَعَ بَعۡضَكُمۡ فَوۡقَ بَعۡضٖ دَرَجَٰتٖ لِّيَبۡلُوَكُمۡ فِي مَآ ءَاتَىٰكُمۡۗ إِنَّ رَبَّكَ سَرِيعُ ٱلۡعِقَابِ وَإِنَّهُۥ لَغَفُورٞ رَّحِيمُۢ ١٦٥","وهو الذي جعلكم خلائف الأرض ورفع بعضكم فوق بعض درجات ليبلوكم في ما آتاكم إن ربك سريع العقاب وإنه لغفور رحيم","އެކަލާނގެއީ، ބިމުގެ ޚަލީފާ އިން ކަމުގައި، ތިޔަބައިމީހުން ލެއްވި ރަސްކަލާނގެއެވެ. އަދި ތިޔަބައިމީހުން ކުރެ، އެއްބަޔަކު އަނެއްބަޔެއްގެ މައްޗަށް ދަރަޖަ މަތިވެރި ކުރެއްވިއެވެ. (އެއީ) ތިޔަބައިމީހުންނަށް، އެކަލާނގެ ދެއްވި ތަކެއްޗާމެދު، ތިޔަބައިމީހުން އިމްތިހާނުކުރެއްވުމަށްޓަކައެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ޢިގާބު ދެއްވުން އަވަސްވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އަދި ހަމަކަށަވަރުން، އެކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["₇ سورة الأعراف","1","بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ\n<br><br>\nالٓمٓصٓ ١","بسم الله الرحمن الرحيم المص","ا ل م ص (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["₇ سورة الأعراف","2","كِتَٰبٌ أُنزِلَ إِلَيۡكَ فَلَا يَكُن فِي صَدۡرِكَ حَرَجٞ مِّنۡهُ لِتُنذِرَ بِهِۦ وَذِكۡرَىٰ لِلۡمُؤۡمِنِينَ ٢","كتاب أنزل إليك فلا يكن في صدرك حرج منه لتنذر به وذكرى للمؤمنين","(މި ގުރްއާނަކީ) ކަލޭގެފާނަށް ބާވައިލެއްވި ފޮތެކެވެ. ފަހެ، އެ ފޮތުން އިންޒާރުކުރެއްވުމަށް، ކަލޭގެފާނުގެ ހިތްޕުޅުގައި އެއްވެސް ދަތިކަމެއް އޮތަނުދެއްވާށެވެ! އަދި އެއީ، މުއުމިނުންނަށް ހުރި ހަނދާންކޮށްދިނުމެކެވެ.","",""],["₇ سورة الأعراف","3","ٱتَّبِعُواْ مَآ أُنزِلَ إِلَيۡكُم مِّن رَّبِّكُمۡ وَلَا تَتَّبِعُواْ مِن دُونِهِۦٓ أَوۡلِيَآءَۗ قَلِيلٗا مَّا تَذَكَّرُونَ ٣","اتبعوا ما أنزل إليكم من ربكم ولا تتبعوا من دونه أولياء قليلا ما تذكرون","ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން، ތިޔަބައިމީހުންނަށް ބާވައިލެއްވި ފޮތަށް ތިޔަބައިމީހުން ތަބާ ވާށެވެ! އަދި އެކަލާނގެ ފިޔަވައި، އެހެން އެހީތެރިންތަކަކަށް ތަބާ ނުވާށެވެ! ތިޔަބައިމީހުން ހަނދުމަކުރަނީ، ވަރަށްވެސް މަދުންނެވެ.","",""],["₇ سورة الأعراف","4","وَكَم مِّن قَرۡيَةٍ أَهۡلَكۡنَٰهَا فَجَآءَهَا بَأۡسُنَا بَيَٰتًا أَوۡ هُمۡ قَآئِلُونَ ٤","وكم من قرية أهلكناها فجاءها بأسنا بياتا أو هم قائلون","ތިމަންރަސްކަލާނގެ ކޯފާލައްވައި، ހަލާކު ކުރެއްވީ ކިތައްކިތައް ރަށް ހެއްޔެވެ؟ ފަހެ، ރޭގަނޑުގައި، ނުވަތަ މެންދުރު އެއުރެން ނިދާފައި ތިއްބައި އެ ރަށްތަކަށް ތިމަންރަސްކަލާނގެ އަޒާބު އައެވެ.","",""],["₇ سورة الأعراف","5","فَمَا كَانَ دَعۡوَىٰهُمۡ إِذۡ جَآءَهُم بَأۡسُنَآ إِلَّآ أَن قَالُوٓاْ إِنَّا كُنَّا ظَٰلِمِينَ ٥","فما كان دعواهم إذ جاءهم بأسنا إلا أن قالوا إنا كنا ظالمين","ފަހެ، ތިމަންރަސްކަލާނގެ އަޒާބެއުރެންގެ ގާތަށް އައިހިނދު، ހަމަކަށަވަރުން، ތިމަންމެން އަނިޔާވެރިން ކަމުގައި ވެއްޖައީމުއޭ ބުނުން ނޫން އެހެން ބުނުމެއް، އެއުރެންގެ ނެތެވެ.","",""],["₇ سورة الأعراف","6","فَلَنَسۡـَٔلَنَّ ٱلَّذِينَ أُرۡسِلَ إِلَيۡهِمۡ وَلَنَسۡـَٔلَنَّ ٱلۡمُرۡسَلِينَ ٦","فلنسألن الذين أرسل إليهم ولنسألن المرسلين","ހަމަށަވަރުން، އެއުރެންގެ ގާތަށް ރަސޫލުން ފޮނުއްވި މީހުންނާ ތިމަންރަސްކަލާނގެ ސުވާލުކުރައްވާ ހުށީމެވެ. އަދި ރަސޫލުންނާވެސް، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ސުވާލުކުރައްވާ ހުށީމެވެ.","",""],["₇ سورة الأعراف","7","فَلَنَقُصَّنَّ عَلَيۡهِم بِعِلۡمٖۖ وَمَا كُنَّا غَآئِبِينَ ٧","فلنقصن عليهم بعلم وما كنا غائبين","އަދި (އެއުރެންކުރި ހުރިހާކަމެއް) ދެނެވޮޑިގެންވާ ޙާލުގައި، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ކިޔައިދެއްވާ ހުށީމެވެ. އަދި (މި ކަމުގައި) ތިމަންރަސްކަލާނގެ ދުރުވެވޮޑިގެނެއް ނުވަމެވެ.","",""],["₇ سورة الأعراف","8","وَٱلۡوَزۡنُ يَوۡمَئِذٍ ٱلۡحَقُّۚ فَمَن ثَقُلَتۡ مَوَٰزِينُهُۥ فَأُوْلَـٰٓئِكَ هُمُ ٱلۡمُفۡلِحُونَ ٨","والوزن يومئذ الحق فمن ثقلت موازينه فأولئك هم المفلحون","އެދުވަހުން (މީސްތަކުންގެ ޢަމަލުތައް) ކިރައި ވަޒަން ކުރައްވާހުށީ ހައްގު ގޮތުގައެވެ. ފަހެ، އެމީހެއްގެ (ހެޔޮ ޢަމަލުތަކުގެ) ތިލަފަތްތައް ބަރުވެއްޖެ މީހާ (ދަންނާށެވެ!) ފަހެ، ދިންނަވާނޭ މީހުންނަކީ ހަމަ އެއުރެންނެވެ.","",""],["₇ سورة الأعراف","9","وَمَنۡ خَفَّتۡ مَوَٰزِينُهُۥ فَأُوْلَـٰٓئِكَ ٱلَّذِينَ خَسِرُوٓاْ أَنفُسَهُم بِمَا كَانُواْ بِـَٔايَٰتِنَا يَظۡلِمُونَ ٩","ومن خفت موازينه فأولئك الذين خسروا أنفسهم بما كانوا بآياتنا يظلمون","އަދި އެމީހެއްގެ ތިލަފަތްތައް ލުއިވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންނަކީ، ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް އިންކާރު ކޮށް އުޅުމުގެ ސަބަބުން އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް ގެއްލުންދިން މީހުންނެވެ.","",""],["₇ سورة الأعراف","10","وَلَقَدۡ مَكَّنَّـٰكُمۡ فِي ٱلۡأَرۡضِ وَجَعَلۡنَا لَكُمۡ فِيهَا مَعَٰيِشَۗ قَلِيلٗا مَّا تَشۡكُرُونَ ١٠","ولقد مكناكم في الأرض وجعلنا لكم فيها معايش قليلا ما تشكرون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް ބިމުގައި ކަންތައްތައް ފަހިކޮށްދެއްވައި ބާރުވެރިކޮށްދެއްވީމެވެ. އަދި އެތާނގައި، ތިޔަބައިމީހުންނަށް ދިރިއުޅެވޭނެ ގޮތްތަކެއް ލެއްވީމެވެ. (އެހެނެއްކަމަކު) ތިޔަބައިމީހުން ޝުކުރުކުރަނީ ވަރަށްވެސް މަދުންނެވެ.","",""],["₇ سورة الأعراف","11","وَلَقَدۡ خَلَقۡنَٰكُمۡ ثُمَّ صَوَّرۡنَٰكُمۡ ثُمَّ قُلۡنَا لِلۡمَلَـٰٓئِكَةِ ٱسۡجُدُواْ لِأٓدَمَ فَسَجَدُوٓاْ إِلَّآ إِبۡلِيسَ لَمۡ يَكُن مِّنَ ٱلسَّـٰجِدِينَ ١١","ولقد خلقناكم ثم صورناكم ثم قلنا للملائكة اسجدوا لآدم فسجدوا إلا إبليس لم يكن من الساجدين","އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން (އެބަހީ: ތިޔަބައިމީހުންގެ އަޞްލުކަމުގައިވާ އާދަމުގެފާނު) ހެއްދެވީމެވެ. ދެން ތިޔަބައިމީހުން (އެބަހީ: އާދަމުގެފާނު) ޞޫރަކުރެއްވީމެވެ. ދެން މަލާއިކަތުންނަށް ވަހީކުރެއްވީމެވެ. އާދަމުގެފާނަށް ތިޔަބައިމީހުން ސަޖިދަކުރާށެވެ! ދެން އިބްލީސް ފިޔަވައި، އެއުރެން ސަޖިދަކުރިއެވެ. ސަޖިދަކުރި މީހުންގެ ތެރެއިން އޭނާ ނުވެއެވެ.","",""],["₇ سورة الأعراف","12","قَالَ مَا مَنَعَكَ أَلَّا تَسۡجُدَ إِذۡ أَمَرۡتُكَۖ قَالَ أَنَا۠ خَيۡرٞ مِّنۡهُ خَلَقۡتَنِي مِن نَّارٖ وَخَلَقۡتَهُۥ مِن طِينٖ ١٢","قال ما منعك ألا تسجد إذ أمرتك قال أنا خير منه خلقتني من نار وخلقته من طين","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ތިމަންރަސްކަލާނގެ ކަލެޔަށް އަމުރުކުރެއްވިހިނދު ސަޖިދަކުރުން ކަލެޔަށް މަނާކުރީ ކޮންކަމެއް ހެއްޔެވެ؟ އެކަލޭގެ ދެންނެވިއެވެ. އެކަލޭގެފާނަށްވުރެ ތިމަން މާމޮޅެވެ. އިބަރަސްކަލާނގެ ތިމަން ހެއްދެވީ އަލިފާނުންނެވެ. އަދި އިބަރަސްކަލާނގެ އެކަލޭގެފާނު ހެއްދެވީ މަށީންނެވެ.","",""],["₇ سورة الأعراف","13","قَالَ فَٱهۡبِطۡ مِنۡهَا فَمَا يَكُونُ لَكَ أَن تَتَكَبَّرَ فِيهَا فَٱخۡرُجۡ إِنَّكَ مِنَ ٱلصَّـٰغِرِينَ ١٣","قال فاهبط منها فما يكون لك أن تتكبر فيها فاخرج إنك من الصاغرين","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ތިޔަތަނުން (އެބަހީ: ސުވަރުގެއިން) ކަލޭ ފައިބާށެވެ! ފަހެ، ތިޔަތާނގައި ހުރެ ކަލެޔަކަށް ބޮޑާވެގަތުމެއް ނެތެވެ. ފަހެ، ކަލޭ ނިކުންނާށެވެ! ހަމަކަށަވަރުން، ކަލޭވަނީ ދެރަވެ ނިކަމެތިވެގެންވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["₇ سورة الأعراف","14","قَالَ أَنظِرۡنِيٓ إِلَىٰ يَوۡمِ يُبۡعَثُونَ ١٤","قال أنظرني إلى يوم يبعثون","އެކަލޭގެ ދެންނެވިއެވެ. އެއުރެން ދިރުއްވައި، އަލުން ފޮނުއްވާނޭ ދުވަހާ ހަމަޔަށް ތިމަން ލަހައްޓަވާނދޭވެ!","",""],["₇ سورة الأعراف","15","قَالَ إِنَّكَ مِنَ ٱلۡمُنظَرِينَ ١٥","قال إنك من المنظرين","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ހަމަކަށަވަރުން، ކަލޭވަނީ، ލަހައްޓަވާފައިވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["₇ سورة الأعراف","16","قَالَ فَبِمَآ أَغۡوَيۡتَنِي لَأَقۡعُدَنَّ لَهُمۡ صِرَٰطَكَ ٱلۡمُسۡتَقِيمَ ١٦","قال فبما أغويتني لأقعدن لهم صراطك المستقيم","އެކަލޭގެ ދެންނެވިއެވެ. އިބަރަސްކަލާނގެ ތިމަންނާ ތެދުމަގުން އެއްކިބާ ކުރައްވައި، ލެހެއްޓެވިކަމުގެ ސަބަބުން، ހަމަކަށަވަރުން، އެއުރެން އިބަރަސްކަލާނގެ ތެދުމަގަށް ވާޞިލު ވުމަށް ހުރަސް އަޅާހުށީމެވެ.","",""],["₇ سورة الأعراف","17","ثُمَّ لَأٓتِيَنَّهُم مِّنۢ بَيۡنِ أَيۡدِيهِمۡ وَمِنۡ خَلۡفِهِمۡ وَعَنۡ أَيۡمَٰنِهِمۡ وَعَن شَمَآئِلِهِمۡۖ وَلَا تَجِدُ أَكۡثَرَهُمۡ شَٰكِرِينَ ١٧","ثم لآتينهم من بين أيديهم ومن خلفهم وعن أيمانهم وعن شمائلهم ولا تجد أكثرهم شاكرين","ދެން އެއުރެންގެ ކުރިމަތިންނާއި، ފަހަތުންނާއި، އެއުރެންގެ ކަނާތްފަރާތުންނާއި ވާތްފަރާތުން (ވަސްވާސްދިނުމަށް) އެއުރެންގެ ގާތަށް ތިމަން އަންނަ ހުށީމެވެ. އަދި އޭގެ ގިނަމީހުންނަކީ، ޝުކުރުކުރާ މީހުން ކަމުގައި އިބަރަސްކަލާނގެ ދެކެވޮޑިއެއް ނުގަންނަވާނޫއެވެ.","",""],["₇ سورة الأعراف","18","قَالَ ٱخۡرُجۡ مِنۡهَا مَذۡءُومٗا مَّدۡحُورٗاۖ لَّمَن تَبِعَكَ مِنۡهُمۡ لَأَمۡلَأَنَّ جَهَنَّمَ مِنكُمۡ أَجۡمَعِينَ ١٨","قال اخرج منها مذءوما مدحورا لمن تبعك منهم لأملأن جهنم منكم أجمعين","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. މަލާމާތް ލިބި، ރަހުމަތުން ދުރުކުރައްވާފައިވާ ޙާލު، ތިޔަތަނުން ކަލޭ ނުކުންނާށެވެ! އެއުރެންގެ ތެރެއިން ކަލެޔަށް ތަބާ ވީ މީހުންނާއި، ތިޔަ އެންމެން އަޅުއްވައި، ތިމަންރަސްކަލާނގެ ނަރަކަ ފުރުއްވާހުށީމެވެ.","",""],["₇ سورة الأعراف","19","وَيَـٰٓـَٔادَمُ ٱسۡكُنۡ أَنتَ وَزَوۡجُكَ ٱلۡجَنَّةَ فَكُلَا مِنۡ حَيۡثُ شِئۡتُمَا وَلَا تَقۡرَبَا هَٰذِهِ ٱلشَّجَرَةَ فَتَكُونَا مِنَ ٱلظَّـٰلِمِينَ ١٩","ويا آدم اسكن أنت وزوجك الجنة فكلا من حيث شئتما ولا تقربا هذه الشجرة فتكونا من الظالمين","އޭ އާދަމުގެފާނެވެ! ކަލޭގެފާނާއި، ކަލޭގެފާނުގެ އަނބިކަނބަލުން ސުވަރުގޭގައި އުޅުއްވާށެވެ! ފަހެ، ތިޔަ ދެކަނބަލުން ބޭނުން އެއްޗަކުން ފަރިއްކުޅުއްވާށެވެ! (އެކަމަކު) ތިޔަ ދެކަނބަލުން، މިހިރަ ގަހާ ކައިރިވެވަޑައިނުގަންނަވާހުށިކަމެވެ! ފަހެ، (ކައިރިވެވަޑައިގެންފިނަމަ) އޭރުން ތިޔަ ދެކަނބަލުން ވާހުށީ، އަނިޔާވެރިންގެ ތެރެއިންނެވެ.","",""],["₇ سورة الأعراف","20","فَوَسۡوَسَ لَهُمَا ٱلشَّيۡطَٰنُ لِيُبۡدِيَ لَهُمَا مَا وُۥرِيَ عَنۡهُمَا مِن سَوۡءَٰتِهِمَا وَقَالَ مَا نَهَىٰكُمَا رَبُّكُمَا عَنۡ هَٰذِهِ ٱلشَّجَرَةِ إِلَّآ أَن تَكُونَا مَلَكَيۡنِ أَوۡ تَكُونَا مِنَ ٱلۡخَٰلِدِينَ ٢٠","فوسوس لهما الشيطان ليبدي لهما ما ووري عنهما من سوآتهما وقال ما نهاكما ربكما عن هذه الشجرة إلا أن تكونا ملكين أو تكونا من الخالدين","ދެންފަހެ، އެ ދެކަނބަލުންގެ ޢައުރަ އިން އެ ދެކަނބަލުންނަށް ނިވައިވެގެންވާ ތަން ފާޅުކުރުމަށްޓަކައި، އެ ދެކަނބަލުންނަށް ޝައިތާނާ ވަސްވާސްދިނެވެ. އަދި އެކަލޭގެ ދެންނެވިއެވެ. ތިޔަ ދެކަނބަލުން ދެ މަލާއިކަތުން ކަމުގައި ވެދާނެ ކަމަށްޓަކައި، ނުވަތަ އަބަދަށް ދެމިތިބެނިވި މީހުންގެ ތެރެއިން ތިޔަ ދެކަނބަލުން ވެދާނެކަމަށްޓަކައި މެނުވީ ތިޔަ ދެކަނބަލުންގެ ވެރިރަސްކަލާނގެ ތިޔަ ދެކަނބަލުން އެގަހާ ކައިރިވެވަޑައިގަތުން މަނާއެއް ނުކުރައްވަތެވެ.","",""],["₇ سورة الأعراف","21","وَقَاسَمَهُمَآ إِنِّي لَكُمَا لَمِنَ ٱلنَّـٰصِحِينَ ٢١","وقاسمهما إني لكما لمن الناصحين","އަދި އެކަލޭގެ ހުވާކޮށް، އެ ދެކަނބަލުންނަށް ދެންނެވިއެވެ. ހަމަކަށަވަރުން، ތިމަންނާވަނީ، ތިޔަ ދެކަނބަލުންނަށް ހެޔޮ ނަސޭހަތް ދޭ މީހުންގެ ތެރެއިންކަން ކަށަވަރެވެ.","",""],["₇ سورة الأعراف","22","فَدَلَّىٰهُمَا بِغُرُورٖۚ فَلَمَّا ذَاقَا ٱلشَّجَرَةَ بَدَتۡ لَهُمَا سَوۡءَٰتُهُمَا وَطَفِقَا يَخۡصِفَانِ عَلَيۡهِمَا مِن وَرَقِ ٱلۡجَنَّةِۖ وَنَادَىٰهُمَا رَبُّهُمَآ أَلَمۡ أَنۡهَكُمَا عَن تِلۡكُمَا ٱلشَّجَرَةِ وَأَقُل لَّكُمَآ إِنَّ ٱلشَّيۡطَٰنَ لَكُمَا عَدُوّٞ مُّبِينٞ ٢٢","فدلاهما بغرور فلما ذاقا الشجرة بدت لهما سوآتهما وطفقا يخصفان عليهما من ورق الجنة وناداهما ربهما ألم أنهكما عن تلكما الشجرة وأقل لكما إن الشيطان لكما عدو مبين","މަކަރުވެރިކަމުން އެކަލޭގެ އެ ދެކަނބަލުން ހަލާކުގެ ތެރެޔަށް ވައްޓާލިއެވެ. ދެންފަހެ، އެ ދެކަނބަލުން، އެ ގަހުން ރަހަބެއްލެވިހިނދު، އެ ދެކަނބަލުންގެ ޢައުރަ އެ ދެކަނބަލުންނަށް ފާޅުވެއްޖެއެވެ. އަދި އެ ދެކަނބަލުން ސުވަރުގޭގެ (ގަހުގެ) ފަތްތަކުން (ޢައުރަ) ނިވާކުރެއްވުމަށް އަވަސްވެވަޑައިގަތެވެ. އަދި އެ ދެކަނބަލުންގެ ވެރިރަސްކަލާނގެ، އެ ދެކަނބަލުންނަށް ނިދާ އިއްވެވިއެވެ. އެގަހާ ކައިރިވެވަޑައިގަތުން ތިމަންރަސްކަލާނގެ ތިޔަ ދެކަނބަލުންނަށް ނަހީ ނުކުރައްވަން ހެއްޔެވެ؟ އަދި ހަމަކަށަވަރުން، ޝައިތާނާއީ، ތިޔަ ދެކަނބަލުންނަށް ބަޔާން ވެގެންހުރި އަދާވަތް ތެރިއެއް ކަމަށް ވަހީ ނުކުރައްވަން ހެއްޔެވެ؟","",""],["₇ سورة الأعراف","23","قَالَا رَبَّنَا ظَلَمۡنَآ أَنفُسَنَا وَإِن لَّمۡ تَغۡفِرۡ لَنَا وَتَرۡحَمۡنَا لَنَكُونَنَّ مِنَ ٱلۡخَٰسِرِينَ ٢٣","قالا ربنا ظلمنا أنفسنا وإن لم تغفر لنا وترحمنا لنكونن من الخاسرين","އެ ދެކަނބަލުން ދެންނެވިއެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެންގެ އަމިއްލަ ނަފްސުތަކަށް އަޅަމެން އަނިޔާވެރި ވެއްޖައީމުއެވެ. އަދި އަޅަމެންނަށް އިބަރަސްކަލާނގެ ފާފަ ނުފުއްސަވައިފިނަމަ، އަދި ރަހުމަތް ނުލައްވައިފިނަމަ، އަޅަމެންވާހުށީ، ގެއްލެނިވެގެންވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["₇ سورة الأعراف","24","قَالَ ٱهۡبِطُواْ بَعۡضُكُمۡ لِبَعۡضٍ عَدُوّٞۖ وَلَكُمۡ فِي ٱلۡأَرۡضِ مُسۡتَقَرّٞ وَمَتَٰعٌ إِلَىٰ حِينٖ ٢٤","قال اهبطوا بعضكم لبعض عدو ولكم في الأرض مستقر ومتاع إلى حين","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ތިޔަބައިމީހުންގެ އެއްބަޔަކު އަނެއްބަޔަކާ އަދާވަތް ތެރިން ކަމުގައިވާ ޙާލު، ތިޔަބައިމީހުން (ބިމަށް) ފައިބާށެވެ! އަދި ބިމުގައި ތިޔަބައިމީހުންނަށްޓަކައި، ގަރާރުވެ ތިބެނިވި ތަނަކާއި، ހިނދުކޮޅަކަށް ދުނިޔޭގެ ވަގުތީ އުފަލެއްވެއެވެ.","",""],["₇ سورة الأعراف","25","قَالَ فِيهَا تَحۡيَوۡنَ وَفِيهَا تَمُوتُونَ وَمِنۡهَا تُخۡرَجُونَ ٢٥","قال فيها تحيون وفيها تموتون ومنها تخرجون","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ތިޔަބައިމީހުން ދިރިއުޅޭހުށީ، އެތާނގައެވެ. އަދި މަރުވާހުށީވެސް އެތާނގައެވެ. އަދި (ގިޔާމަތް ދުވަހުން ދިރުއްވައި) ނެރުއްވާހުށީވެސް އެތަނުންނެވެ.","",""],["₇ سورة الأعراف","26","يَٰبَنِيٓ ءَادَمَ قَدۡ أَنزَلۡنَا عَلَيۡكُمۡ لِبَاسٗا يُوَٰرِي سَوۡءَٰتِكُمۡ وَرِيشٗاۖ وَلِبَاسُ ٱلتَّقۡوَىٰ ذَٰلِكَ خَيۡرٞۚ ذَٰلِكَ مِنۡ ءَايَٰتِ ٱللَّهِ لَعَلَّهُمۡ يَذَّكَّرُونَ ٢٦","يا بني آدم قد أنزلنا عليكم لباسا يواري سوآتكم وريشا ولباس التقوى ذلك خير ذلك من آيات الله لعلهم يذكرون","އޭ އާދަމުގެދަރިންނޭވެ! ތިޔަބައިމީހުންގެ ޢައުރަތައް ނިވައިކުރަނިވި ހެދުމާއި، ޒީނަތްތެރި ފޭރާން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް ދެއްވީމެވެ. އަދި ތަގުވާގެ ފޭރާން މާހެޔޮކަން ބޮޑެވެ. އެކަންތައްތައްވަނީ، ﷲގެ އާޔަތްތަކުގެ ތެރެއިންނެވެ. (އެއީ) އެއުރެން ހަނދުމަ ކުރުމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","27","يَٰبَنِيٓ ءَادَمَ لَا يَفۡتِنَنَّكُمُ ٱلشَّيۡطَٰنُ كَمَآ أَخۡرَجَ أَبَوَيۡكُم مِّنَ ٱلۡجَنَّةِ يَنزِعُ عَنۡهُمَا لِبَاسَهُمَا لِيُرِيَهُمَا سَوۡءَٰتِهِمَآۚ إِنَّهُۥ يَرَىٰكُمۡ هُوَ وَقَبِيلُهُۥ مِنۡ حَيۡثُ لَا تَرَوۡنَهُمۡۗ إِنَّا جَعَلۡنَا ٱلشَّيَٰطِينَ أَوۡلِيَآءَ لِلَّذِينَ لَا يُؤۡمِنُونَ ٢٧","يا بني آدم لا يفتننكم الشيطان كما أخرج أبويكم من الجنة ينزع عنهما لباسهما ليريهما سوآتهما إنه يراكم هو وقبيله من حيث لا ترونهم إنا جعلنا الشياطين أولياء للذين لا يؤمنون","އޭ އާދަމުގެދަރިންނޭވެ! ތިޔަބައިމީހުންގެ މައިންބަފައިން ކަމުގައިވި (އާދަމުގެފާނާއި ޙައްވާގެފާނާއި) ދެކަނބަލުންގެ ޢައުރަ އެ ދެކަނބަލުންނަށް ދެއްކުމަށްޓަކައި، އެ ދެކަނބަލުންގެ ފޭރާން ބާލައި، އެ ދެކަނބަލުން ސުވަރުގެއިން ނެރެލިފަދައިން، ޝައިތާނާ ތިޔަބައިމީހުން ހެއްލުންތެރިކުރިޔަ ނުދޭހުށިކަމެވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށް އެ ޝައިތާނުން ނުފެންނަހިނދުގައި، އެ ޝައިތާނާއާއި، އޭނާގެ ލަޝްކަރަށް ތިޔަބައިމީހުން ފެނެއެވެ. ހަމަކަށަވަރުން، އީމާން ނުވާ މީހުންނަށް، ވާގިވެރިވާ ބަޔަކު ކަމުގައި، ތިމަންރަސްކަލާނގެ ޝައިތާނުން ލެއްވީމެވެ.","",""],["₇ سورة الأعراف","28","وَإِذَا فَعَلُواْ فَٰحِشَةٗ قَالُواْ وَجَدۡنَا عَلَيۡهَآ ءَابَآءَنَا وَٱللَّهُ أَمَرَنَا بِهَاۗ قُلۡ إِنَّ ٱللَّهَ لَا يَأۡمُرُ بِٱلۡفَحۡشَآءِۖ أَتَقُولُونَ عَلَى ٱللَّهِ مَا لَا تَعۡلَمُونَ ٢٨","وإذا فعلوا فاحشة قالوا وجدنا عليها آباءنا والله أمرنا بها قل إن الله لا يأمر بالفحشاء أتقولون على الله ما لا تعلمون","އެއުރެން ފާޙީޝްކަމެއް ކޮށްފިނަމަ، ބުނެތެވެ. ތިމަންމެންގެ ކާބަފައިންވެސް އެކަން ކުރުންމަތީވަނިކޮށް ތިމަންމެން ދުށީމުއެވެ. އަދި އެކަމަށް ﷲ ވަނީ، ތިމަންމެންނަށް އަމުރުކުރައްވާފައެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ފާޙީޝްކަމަކަށް ހަމަކަށަވަރުން، ﷲ އަމުރެއް ނުކުރައްވަތެވެ. ތިޔަބައިމީހުންނަށް އެނގިގެންނުވާ އެއްޗެއް ﷲއާމެދު ތިޔަބައިމީހުން ބުނަނީހެއްޔެވެ؟","",""],["₇ سورة الأعراف","29","قُلۡ أَمَرَ رَبِّي بِٱلۡقِسۡطِۖ وَأَقِيمُواْ وُجُوهَكُمۡ عِندَ كُلِّ مَسۡجِدٖ وَٱدۡعُوهُ مُخۡلِصِينَ لَهُ ٱلدِّينَۚ كَمَا بَدَأَكُمۡ تَعُودُونَ ٢٩","قل أمر ربي بالقسط وأقيموا وجوهكم عند كل مسجد وادعوه مخلصين له الدين كما بدأكم تعودون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އަމުރުކުރެއްވީ ޢަދުލުވެރިވުމަށެވެ. އަދި ތިޔަބައިމީހުން ނަމާދުކުރާ ކޮންމެ ހިނދަކު، ތިޔަބައިމީހުންގެ މޫނުތައް (ގިބްލަށް) ސީދާ ކުރާށެވެ! އަދި ތިޔަބައިމީހުން، އެކަލާނގެއަށް އަޅުކަން ޚާލިސްކުރާ ޙާލު، އެކަލާނގެއަށް އަޅުކަންކޮށް ދުއާކުރާށެވެ! އެކަލާނގެ ތިޔަބައިމީހުން ފުރަތަމަ އުފެއްދެވި ފަދައިން، ތިޔަބައިމީހުން އަލުން އެނބުރި އަންނަހުށްޓެވެ.","",""],["₇ سورة الأعراف","30","فَرِيقًا هَدَىٰ وَفَرِيقًا حَقَّ عَلَيۡهِمُ ٱلضَّلَٰلَةُۚ إِنَّهُمُ ٱتَّخَذُواْ ٱلشَّيَٰطِينَ أَوۡلِيَآءَ مِن دُونِ ٱللَّهِ وَيَحۡسَبُونَ أَنَّهُم مُّهۡتَدُونَ ٣٠","فريقا هدى وفريقا حق عليهم الضلالة إنهم اتخذوا الشياطين أولياء من دون الله ويحسبون أنهم مهتدون","އެއްބަޔަކަށް، އެކަލާނގެ ތެދުމަގު ދެއްކެވިއެވެ. އަދި އަނެއް ބަޔެއްގެ މައްޗަށް ވަނީ މަގުފުރެދުން ހައްގު ވެފައެވެ. ހަމަކަށަވަރުން، އެއުރެން ﷲ ފިޔަވައި ޝައިތާނުންނަކީ، އެހީތެރިން ކަމުގައި ބެލިއެވެ. އަދި އެއުރެންނީ ތެދުމަގު ލިބިގެންވާ ބަޔަކު ކަމުގައި އެއުރެން ހީކުރެތެވެ.","",""],["₇ سورة الأعراف","31","۞يَٰبَنِيٓ ءَادَمَ خُذُواْ زِينَتَكُمۡ عِندَ كُلِّ مَسۡجِدٖ وَكُلُواْ وَٱشۡرَبُواْ وَلَا تُسۡرِفُوٓاْۚ إِنَّهُۥ لَا يُحِبُّ ٱلۡمُسۡرِفِينَ ٣١","يا بني آدم خذوا زينتكم عند كل مسجد وكلوا واشربوا ولا تسرفوا إنه لا يحب المسرفين","އޭ އާދަމުގެދަރިންނޭވެ! ތިޔަބައިމީހުން، ނަމާދުކުރާ ކޮންމެ ހިނދެއްގައިމެ، ޒީނަތްތެރިކަން ހިފާށެވެ! އަދި ތިޔަބައިމީހުން ކައިބޮއި އުޅޭށެވެ! އަދި އިސްރާފު ނުކުރާށެވެ! ހަމަކަށަވަރުން، އިސްރާފުކުރާ މީހުންދެކެ އެކަލާނގެ ލޯބިވެ ވޮޑިގެނެއް ނުވެތެވެ.","",""],["₇ سورة الأعراف","32","قُلۡ مَنۡ حَرَّمَ زِينَةَ ٱللَّهِ ٱلَّتِيٓ أَخۡرَجَ لِعِبَادِهِۦ وَٱلطَّيِّبَٰتِ مِنَ ٱلرِّزۡقِۚ قُلۡ هِيَ لِلَّذِينَ ءَامَنُواْ فِي ٱلۡحَيَوٰةِ ٱلدُّنۡيَا خَالِصَةٗ يَوۡمَ ٱلۡقِيَٰمَةِۗ كَذَٰلِكَ نُفَصِّلُ ٱلۡأٓيَٰتِ لِقَوۡمٖ يَعۡلَمُونَ ٣٢","قل من حرم زينة الله التي أخرج لعباده والطيبات من الرزق قل هي للذين آمنوا في الحياة الدنيا خالصة يوم القيامة كذلك نفصل الآيات لقوم يعلمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲ، އެކަލާނގެ އަޅުތަކުންނަށް ނެރުއްވައިދެއްވި، ﷲގެ ޒީނަތާއި، ރިޒްގުގެ ތެރެއިން ރަނގަޅު ތަކެތި ހަރާމްކުޅައީ ކާކުހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެތަކެތި ވަނީ އީމާން ވީ، މީހުންނަށް ދުންޔަވީ ހަޔާތުގައި ދެއްވާފައެވެ. ގިޔާމަތް ދުވަހުން އެތަކެތި (މުއުމިނުންނަށް) ޚާލިސް ވެގެންވާ ޙާލު ގައެވެ. އެނގޭބަޔަކަށް އެފަދައިން ތިމަންރަސްކަލާނގެ އާޔަތްތައް ތަފްޞީލު ކޮށްދެއްވަމެވެ.","",""],["₇ سورة الأعراف","33","قُلۡ إِنَّمَا حَرَّمَ رَبِّيَ ٱلۡفَوَٰحِشَ مَا ظَهَرَ مِنۡهَا وَمَا بَطَنَ وَٱلۡإِثۡمَ وَٱلۡبَغۡيَ بِغَيۡرِ ٱلۡحَقِّ وَأَن تُشۡرِكُواْ بِٱللَّهِ مَا لَمۡ يُنَزِّلۡ بِهِۦ سُلۡطَٰنٗا وَأَن تَقُولُواْ عَلَى ٱللَّهِ مَا لَا تَعۡلَمُونَ ٣٣","قل إنما حرم ربي الفواحش ما ظهر منها وما بطن والإثم والبغي بغير الحق وأن تشركوا بالله ما لم ينزل به سلطانا وأن تقولوا على الله ما لا تعلمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަރާމްކުރެއްވިކަން ކަށަވަރީ، ފާޙީޝް ކަންތައްތަކެވެ. އޭގެތެރެއިން ފާޅުވެގެންވާ ކަންތަކާއި ވަންހަނާ ވެގެންވާ ކަންތަކެވެ. އަދި ފާފަކުރުމާއި، ހައްގަކާ ނުލައި (މީސްތަކުންނަށް) އަނިޔާވެރިވުމެވެ. އަދި އެ އެއްޗަކަށް އެއްވެސް ހުއްޖަތެއް ދެއްވާފައި ނުވާ އެއްޗެއް، ތިޔަބައިމީހުން، ﷲއަށް ޝަރީކުކުރުމެވެ. އަދި ތިޔަބައިމީހުންނަށް އެނގިގެންނުވާ އެއްޗެއް، ﷲއާމެދު ތިޔަބައިމީހުން ބުނުމެވެ.","",""],["₇ سورة الأعراف","34","وَلِكُلِّ أُمَّةٍ أَجَلٞۖ فَإِذَا جَآءَ أَجَلُهُمۡ لَا يَسۡتَأۡخِرُونَ سَاعَةٗ وَلَا يَسۡتَقۡدِمُونَ ٣٤","ولكل أمة أجل فإذا جاء أجلهم لا يستأخرون ساعة ولا يستقدمون","ކޮންމެ އުއްމަތަކަށްމެ އަޖަލެއް ވެއެވެ. ފަހެ، އެއުރެންގެ އަޖަލު އައުމުން، އެންމެ ހިނދުކޮޅަކަށްވެސް އެއުރެންނަކަށް ލަހެއްނުކުރައްވާ ހުށްޓެވެ. އަދި އަވަހެއްވެސް ނުމެކުރައްވާ ހުށްޓެވެ.","",""],["₇ سورة الأعراف","35","يَٰبَنِيٓ ءَادَمَ إِمَّا يَأۡتِيَنَّكُمۡ رُسُلٞ مِّنكُمۡ يَقُصُّونَ عَلَيۡكُمۡ ءَايَٰتِي فَمَنِ ٱتَّقَىٰ وَأَصۡلَحَ فَلَا خَوۡفٌ عَلَيۡهِمۡ وَلَا هُمۡ يَحۡزَنُونَ ٣٥","يا بني آدم إما يأتينكم رسل منكم يقصون عليكم آياتي فمن اتقى وأصلح فلا خوف عليهم ولا هم يحزنون","އޭ އާދަމުގެދަރިންނޭވެ! ތިމަންރަސްކަލާނގެ އާޔަތްތައް، ތިޔަބައިމީހުންނަށް ކިޔައިދެއްވާ ރަސޫލުންތަކެއް، ތިޔަބައިމީހުންގެ ތެރެއިން ތިޔަބައިމީހުންގެ ގާތަށް ވަޑައިގެންފިނަމަ، ފަހެ، ތަގުވާވެރިވެ، އަދި (ޢަމަލުތައް) އިސްލާހު ކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންގެ މައްޗަކަށް އެއްވެސް ބިރެއް ނެތެވެ. އަދި އެއުރެންނީ، ހިތާމަކުރާނޭ ބަޔަކު ކަމުގައިވެސް ނުމެވޭމެއެވެ.","",""],["₇ سورة الأعراف","36","وَٱلَّذِينَ كَذَّبُواْ بِـَٔايَٰتِنَا وَٱسۡتَكۡبَرُواْ عَنۡهَآ أُوْلَـٰٓئِكَ أَصۡحَٰبُ ٱلنَّارِۖ هُمۡ فِيهَا خَٰلِدُونَ ٣٦","والذين كذبوا بآياتنا واستكبروا عنها أولئك أصحاب النار هم فيها خالدون","އަދި ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކޮށް، އަދި އެއާމެދު ކިބުރުވެރިވެގަތް މީހުން އެއީ، ނަރަކައިގެ އަހުލުވެރިންނެވެ. އެއުރެންނީ އެތާނގައި ދެމިތިބޭނޭ މީހުންނެވެ.","",""],["₇ سورة الأعراف","37","فَمَنۡ أَظۡلَمُ مِمَّنِ ٱفۡتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَوۡ كَذَّبَ بِـَٔايَٰتِهِۦٓۚ أُوْلَـٰٓئِكَ يَنَالُهُمۡ نَصِيبُهُم مِّنَ ٱلۡكِتَٰبِۖ حَتَّىٰٓ إِذَا جَآءَتۡهُمۡ رُسُلُنَا يَتَوَفَّوۡنَهُمۡ قَالُوٓاْ أَيۡنَ مَا كُنتُمۡ تَدۡعُونَ مِن دُونِ ٱللَّهِۖ قَالُواْ ضَلُّواْ عَنَّا وَشَهِدُواْ عَلَىٰٓ أَنفُسِهِمۡ أَنَّهُمۡ كَانُواْ كَٰفِرِينَ ٣٧","فمن أظلم ممن افترى على الله كذبا أو كذب بآياته أولئك ينالهم نصيبهم من الكتاب حتى إذا جاءتهم رسلنا يتوفونهم قالوا أين ما كنتم تدعون من دون الله قالوا ضلوا عنا وشهدوا على أنفسهم أنهم كانوا كافرين","ﷲއާމެދު ހަދައިގެން ދޮގުބުނި މީހަކަށްވުރެން، ނުވަތަ އެކަލާނގެ އާޔަތްތައް ދޮގުކުޅަ މީހަކަށްވުރެން، އަނިޔާވެރިކަން ބޮޑީ ފަހެ، ކާކުހެއްޔެވެ؟ އެއުރެންނަށްޓަކައި ލިޔުއްވާފައިވާ މިންވަރު އެއުރެންނަށް ލިބޭނެތެވެ. އެއުރެންގެ މަރު ހިއްޕެވުމަށް، ތިމަންރަސްކަލާނގެ ފޮނުއްވާ މަލާއިކަތުން ވަޑައިގެންފުމަށް ދާނދެނެވެ. އެހިނދު އެބޭކަލުން ވިދާޅުވާނެތެވެ. ﷲ ފިޔަވައި ތިޔަބައިމީހުން އަޅުކަންކޮށް އުޅުނު ތަކެތި ކޮބައިހެއްޔެވެ؟ އެއުރެން ދަންނަވާނެތެވެ. އެތަކެތި ތިމަންމެންނަށް ގެއްލިއްޖެއެވެ. އަދި އެއުރެންނީ ކާފިރުން ކަމުގައި އެއުރެންގެ އަމިއްލަ ނަފްސުތަކުގެ މައްޗަށް އެއުރެން ހެކިވެއްޖައޫއެވެ.","",""],["₇ سورة الأعراف","38","قَالَ ٱدۡخُلُواْ فِيٓ أُمَمٖ قَدۡ خَلَتۡ مِن قَبۡلِكُم مِّنَ ٱلۡجِنِّ وَٱلۡإِنسِ فِي ٱلنَّارِۖ كُلَّمَا دَخَلَتۡ أُمَّةٞ لَّعَنَتۡ أُخۡتَهَاۖ حَتَّىٰٓ إِذَا ٱدَّارَكُواْ فِيهَا جَمِيعٗا قَالَتۡ أُخۡرَىٰهُمۡ لِأُولَىٰهُمۡ رَبَّنَا هَـٰٓؤُلَآءِ أَضَلُّونَا فَـَٔاتِهِمۡ عَذَابٗا ضِعۡفٗا مِّنَ ٱلنَّارِۖ قَالَ لِكُلّٖ ضِعۡفٞ وَلَٰكِن لَّا تَعۡلَمُونَ ٣٨","قال ادخلوا في أمم قد خلت من قبلكم من الجن والإنس في النار كلما دخلت أمة لعنت أختها حتى إذا اداركوا فيها جميعا قالت أخراهم لأولاهم ربنا هؤلاء أضلونا فآتهم عذابا ضعفا من النار قال لكل ضعف ولكن لا تعلمون","އެކަލާނގެ ވަހީކުރައްވާނެތެވެ. ޖިންނީންނާއި، އިންސީންގެ ތެރެއިން ތިޔަބައިމީހުންގެ ކުރިން އިސްވެގޮސްފައިވާ (އަނިޔާވެރި) ބައިގަނޑަކާއެކު ތިޔަބައިމީހުން ނަރަކައަށް ވަންނާށެވެ! އޭގެތެރެއިން ބަޔަކު (ނަރަކަޔަށް) ވަންނަ ކޮންމެފަހަރަކު، އެބަޔަކު އެފަދަ އަނެއްބަޔަކަށް ލައުނަތް ދެއެވެ. އެ އެންމެން ނަރަކައަށް ޖަމަޢުވެ ނިމުމުން އެއުރެންކުރެ ފަހުގެ މީހުން ކުރީގެ މީހުންނާމެދު ބުނާނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! އަޅަމެން މަގުފުރެއްދީ މިތިބަ މީހުންނެވެ. ފަހެ، އެއުރެންނަށް ނަރަކައިގެ އަޒާބު ދެގުނައަށް ދެއްވާނދޭވެ! އެކަލާނގެ ވަހީކުރައްވާނެތެވެ. ތިޔައިން ކޮންމެ ބަޔަކަށްވެސް ދެގުނަޔަށް (އަޒާބު) ހުށްޓެވެ. އެހެނެއްކަމަކު، ތިޔަބައިމީހުންނަކަށް ނޭނގެއެވެ.","",""],["₇ سورة الأعراف","39","وَقَالَتۡ أُولَىٰهُمۡ لِأُخۡرَىٰهُمۡ فَمَا كَانَ لَكُمۡ عَلَيۡنَا مِن فَضۡلٖ فَذُوقُواْ ٱلۡعَذَابَ بِمَا كُنتُمۡ تَكۡسِبُونَ ٣٩","وقالت أولاهم لأخراهم فما كان لكم علينا من فضل فذوقوا العذاب بما كنتم تكسبون","އަދި އެއުރެންކުރެ ކުރީގެ މީހުން ފަހުގެ މީހުންނަށް ބުނާނެތެވެ. ފަހެ، ތިމަންމެންގެ މައްޗަށް ތިޔަބައިމީހުންނަކަށް އިތުރު ކަމެއް ނެތެވެ. ފަހެ، ތިޔަބައިމީހުން ހޯދައި އުޅުނު (ނުބައި) ޢަމަލުތަކުގެ ސަބަބުން ތިޔަބައިމީހުން އަޒާބުގެ ރަހަ ލިބިގަންނާށެވެ!","",""],["₇ سورة الأعراف","40","إِنَّ ٱلَّذِينَ كَذَّبُواْ بِـَٔايَٰتِنَا وَٱسۡتَكۡبَرُواْ عَنۡهَا لَا تُفَتَّحُ لَهُمۡ أَبۡوَٰبُ ٱلسَّمَآءِ وَلَا يَدۡخُلُونَ ٱلۡجَنَّةَ حَتَّىٰ يَلِجَ ٱلۡجَمَلُ فِي سَمِّ ٱلۡخِيَاطِۚ وَكَذَٰلِكَ نَجۡزِي ٱلۡمُجۡرِمِينَ ٤٠","إن الذين كذبوا بآياتنا واستكبروا عنها لا تفتح لهم أبواب السماء ولا يدخلون الجنة حتى يلج الجمل في سم الخياط وكذلك نجزي المجرمين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކޮށް، އަދި އެ އާޔަތް ތަކާމެދު ކިބުރުވެރިވެގަންނަ މީހުން (ދަންނާށެވެ!) އެއުރެންނަށްޓަކައި، އުޑުގެ ދޮރުތައް ހުޅުވިގެން ނުދާހުށްޓެވެ. އަދި ތިނޯހުގެ ފަގަޔަށް ޖަމަލު ވަދެއްޖައުމަށް ދާނދެން އެއުރެން ސުވަރުގެ ނުވަންނަހުށްޓެވެ. ކުށްވެރިންނަށް ތިމަންރަސްކަލާނގެ ޖަޒާ ދެއްވަނީ އެފަދައިންނެވެ.","",""],["₇ سورة الأعراف","41","لَهُم مِّن جَهَنَّمَ مِهَادٞ وَمِن فَوۡقِهِمۡ غَوَاشٖۚ وَكَذَٰلِكَ نَجۡزِي ٱلظَّـٰلِمِينَ ٤١","لهم من جهنم مهاد ومن فوقهم غواش وكذلك نجزي الظالمين","އެއުރެންނަށް ނަރަކައިގެ ދާނެއްވެއެވެ. އަދި އެއުރެންގެ ގައިމަތީ (އަލިފާނުގެ) ސާލުތަކެއްވެއެވެ. އަނިޔާވެރިންނަށް ތިމަންރަސްކަލާނގެ ޖަޒާ ދެއްވަނީ އެފަދައިންނެވެ.","",""],["₇ سورة الأعراف","42","وَٱلَّذِينَ ءَامَنُواْ وَعَمِلُواْ ٱلصَّـٰلِحَٰتِ لَا نُكَلِّفُ نَفۡسًا إِلَّا وُسۡعَهَآ أُوْلَـٰٓئِكَ أَصۡحَٰبُ ٱلۡجَنَّةِۖ هُمۡ فِيهَا خَٰلِدُونَ ٤٢","والذين آمنوا وعملوا الصالحات لا نكلف نفسا إلا وسعها أولئك أصحاب الجنة هم فيها خالدون","އަދި އީމާންވެ، ސާލިހު ޢަމަލުކުޅަމީހުން (ދަންނާށެވެ!) ތިމަންރަސްކަލާނގެ އެއްވެސް ނަފްސަކަށް، އެ ނަފްސަކަށް ކުޅަދާނަ ވެގެންވާ މިންވަރަކަށް މެނުވީ ތަކުލީފެއް ނުޖައްސަވަމެވެ. އެއުރެންނީ، ސުވަރުގޭގެ އަހުލުވެރިންނެވެ. އެއުރެންނީ، އެތާނގައި ދެމިތިބެނިވި ބަޔެކެވެ.","",""],["₇ سورة الأعراف","43","وَنَزَعۡنَا مَا فِي صُدُورِهِم مِّنۡ غِلّٖ تَجۡرِي مِن تَحۡتِهِمُ ٱلۡأَنۡهَٰرُۖ وَقَالُواْ ٱلۡحَمۡدُ لِلَّهِ ٱلَّذِي هَدَىٰنَا لِهَٰذَا وَمَا كُنَّا لِنَهۡتَدِيَ لَوۡلَآ أَنۡ هَدَىٰنَا ٱللَّهُۖ لَقَدۡ جَآءَتۡ رُسُلُ رَبِّنَا بِٱلۡحَقِّۖ وَنُودُوٓاْ أَن تِلۡكُمُ ٱلۡجَنَّةُ أُورِثۡتُمُوهَا بِمَا كُنتُمۡ تَعۡمَلُونَ ٤٣","ونزعنا ما في صدورهم من غل تجري من تحتهم الأنهار وقالوا الحمد لله الذي هدانا لهذا وما كنا لنهتدي لولا أن هدانا الله لقد جاءت رسل ربنا بالحق ونودوا أن تلكم الجنة أورثتموها بما كنتم تعملون","އަދި އެއުރެންގެ ހިތްތަކުގައިވާ ހަސަދަވެރިކަން، ތިމަންރަސްކަލާނގެ ވަނީ ވަކިކުރައްވާފައެވެ. އެއުރެންގެ ދަށުން ފެންއާރުތައް ހިނގައެވެ. އަދި އެއުރެން ބުނާނެތެވެ. ހަމްދު ހުރީ ތިމަންމެންނަށް މިކަމަށް ތެދުމަގު ދެއްކެވި ﷲއަށެވެ. އަދި ﷲ، ތިމަންމެންނަށް ތެދުމަގު ދައްކަވައިފިއްޔާ މެނުވީ، ތިމަންމެންނަކަށް ތެދުމަގެއް ނުފެނުނީހެވެ. ތިމަންމެންގެ ވެރިރަސްކަލާނގެ ފޮނުއްވި ރަސޫލުން، ހައްގު ދީނާއިގެން ވަޑައިގަތްކަން ކަށަވަރެވެ. ދެން އެއުރެންނަށް ގޮވައި އަންގަވާނެތެވެ. އެހެރީ ސުވަރުގެއެވެ. ތިޔަބައިމީހުން ކޮށްއުޅުނު ޢަމަލުތަކުގެ ސަބަބުން އެތަން ތިޔަބައިމީހުންނަށް ލިބިދެއްވިއެވެ.","",""],["₇ سورة الأعراف","44","وَنَادَىٰٓ أَصۡحَٰبُ ٱلۡجَنَّةِ أَصۡحَٰبَ ٱلنَّارِ أَن قَدۡ وَجَدۡنَا مَا وَعَدَنَا رَبُّنَا حَقّٗا فَهَلۡ وَجَدتُّم مَّا وَعَدَ رَبُّكُمۡ حَقّٗاۖ قَالُواْ نَعَمۡۚ فَأَذَّنَ مُؤَذِّنُۢ بَيۡنَهُمۡ أَن لَّعۡنَةُ ٱللَّهِ عَلَى ٱلظَّـٰلِمِينَ ٤٤","ونادى أصحاب الجنة أصحاب النار أن قد وجدنا ما وعدنا ربنا حقا فهل وجدتم ما وعد ربكم حقا قالوا نعم فأذن مؤذن بينهم أن لعنة الله على الظالمين","ސުވަރުގޭގެ އަހުލުވެރިން، ނަރަކައިގެ އަހުލުވެރިންނަށް ގޮވައި ބުނާނެތެވެ. ތިމަންމެންގެ ވެރިރަސްކަލާނގެ ތިމަންމެންނަށް ވައުދުކުރެއްވި ކަންތައް، ހައްގު ގޮތުގައި ހަމަކަށަވަރުންވެސް ތިމަންމެންނަށް ފެނިއްޖެއެވެ. ފަހެ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ވައުދުކުރެއްވި ކަންތައް، ހައްގު ގޮތުގައި ތިޔަބައިމީހުންނަށް ފެނިއްޖެހެއްޔެވެ؟ އެއުރެން ބުނާނެތެވެ. އާނއެކެވެ! ފަހެ، (އެހިނދު) ގޮވައިލައްވާ ބޭކަލަކު އެއުރެންގެ މެދުގައި ގޮވައިލައްވާނެތެވެ. އަނިޔާވެރިންގެ މައްޗަށް ﷲގެ ލައުނަތް ހުށްޓެވެ.","",""],["₇ سورة الأعراف","45","ٱلَّذِينَ يَصُدُّونَ عَن سَبِيلِ ٱللَّهِ وَيَبۡغُونَهَا عِوَجٗا وَهُم بِٱلۡأٓخِرَةِ كَٰفِرُونَ ٤٥","الذين يصدون عن سبيل الله ويبغونها عوجا وهم بالآخرة كافرون","އެއުރެންނީ، ﷲގެ މަގުން (މީސްތަކުން) އެއްކިބާކުރާ މީހުންނެވެ. އަދި އެ މަގު ގުދު މަގަކަށްވުމަށް އެދޭ މީހުންނެވެ. އަދި އެއުރެންނީ، އާޚިރަތް ދުވަހަށް ކާފިރު ވެގެންވާ މީހުންނެވެ.","",""],["₇ سورة الأعراف","46","وَبَيۡنَهُمَا حِجَابٞۚ وَعَلَى ٱلۡأَعۡرَافِ رِجَالٞ يَعۡرِفُونَ كُلَّۢا بِسِيمَىٰهُمۡۚ وَنَادَوۡاْ أَصۡحَٰبَ ٱلۡجَنَّةِ أَن سَلَٰمٌ عَلَيۡكُمۡۚ لَمۡ يَدۡخُلُوهَا وَهُمۡ يَطۡمَعُونَ ٤٦","وبينهما حجاب وعلى الأعراف رجال يعرفون كلا بسيماهم ونادوا أصحاب الجنة أن سلام عليكم لم يدخلوها وهم يطمعون","އެ ދެބައިމީހުންގެ ދެމެދުގައި، ފަރުދާއެއްވެއެވެ. އަޢުރާފް މަތީގައި (އެބަހީ: ސުވަރުގޭގެ ފާރުމަތީގައި) މީހުންތަކެއް ވެއެވެ. އެއުރެންނަށް އެ ދެބައިމީހުންގެ އަލާމަތް ތަކުން، އެ ދެބައިމީހުން އެނގެއެވެ. އަދި އެއުރެން ސުވަރުގޭގެ އަހުލުވެރިންނަށް ގޮވައިލާނެތެވެ. ތިޔަބައިމީހުންގެ މައްޗަށް ސަލާމް ހުށްޓެވެ. އެއުރެން ތިބޭނީ ސުވަރުގެއަށް ނުވަދެވި، އެކަމުގެ ދަހިވެތިކަމުގައެވެ.","",""],["₇ سورة الأعراف","47","۞وَإِذَا صُرِفَتۡ أَبۡصَٰرُهُمۡ تِلۡقَآءَ أَصۡحَٰبِ ٱلنَّارِ قَالُواْ رَبَّنَا لَا تَجۡعَلۡنَا مَعَ ٱلۡقَوۡمِ ٱلظَّـٰلِمِينَ ٤٧","وإذا صرفت أبصارهم تلقاء أصحاب النار قالوا ربنا لا تجعلنا مع القوم الظالمين","އަދި އެއުރެންގެ ލޯތައް ނަރަކައިގެ އަހުލުވެރިންނާ ދިމާއަށް އަނބުރައިލާހިނދު، އެއުރެން ބުނާނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! އަނިޔާވެރިވީ މީހުންނާ އެކުގައި އަޅަމެން ނުލައްވާނދޭވެ!","",""],["₇ سورة الأعراف","48","وَنَادَىٰٓ أَصۡحَٰبُ ٱلۡأَعۡرَافِ رِجَالٗا يَعۡرِفُونَهُم بِسِيمَىٰهُمۡ قَالُواْ مَآ أَغۡنَىٰ عَنكُمۡ جَمۡعُكُمۡ وَمَا كُنتُمۡ تَسۡتَكۡبِرُونَ ٤٨","ونادى أصحاب الأعراف رجالا يعرفونهم بسيماهم قالوا ما أغنى عنكم جمعكم وما كنتم تستكبرون","އަދި އަޢުރާފްގެ އަހުލުވެރިން، އެބަޔެއްގެ ޢަލާމާތުން އެއުރެން ދަންނަ މީހުންތަކަކަށް ގޮވައި ބުނާނެތެވެ. ތިޔަބައިމީހުންގެ ބައިގިނަކަމާއި، ތިޔަބައިމީހުން ކިބުރުވެރިވެ އުޅުނުކަން (ނަރަކައިގެ އަޒާބުން) ތިޔަބައިމީހުން މިންޖެއް ނުކުރިތާއެވެ!","",""],["₇ سورة الأعراف","49","أَهَـٰٓؤُلَآءِ ٱلَّذِينَ أَقۡسَمۡتُمۡ لَا يَنَالُهُمُ ٱللَّهُ بِرَحۡمَةٍۚ ٱدۡخُلُواْ ٱلۡجَنَّةَ لَا خَوۡفٌ عَلَيۡكُمۡ وَلَآ أَنتُمۡ تَحۡزَنُونَ ٤٩","أهؤلاء الذين أقسمتم لا ينالهم الله برحمة ادخلوا الجنة لا خوف عليكم ولا أنتم تحزنون","އެއުރެންނަށް ﷲ ރަހުމަތެއް ނުލައްވާނޭކަމަށް ތިޔަބައިމީހުން ހުވާކުޅަ މީހުންނަކީ މިތިބީހެއްޔެވެ؟ (އެއުރެންނަށް އަންގަވާނެތެވެ.) ސުވަރުގެއަށް ތިޔަބައިމީހުން ވަންނާށެވެ! ތިޔަބައިމީހުންގެ މައްޗަކަށް އެއްވެސް ބިރެއްނެތެވެ. އަދި ހިތާމަކުރާނޭ ބަޔަކު ކަމުގައިވެސް ތިޔަބައިމީހުން ނުވަމުއެވެ.","",""],["₇ سورة الأعراف","50","وَنَادَىٰٓ أَصۡحَٰبُ ٱلنَّارِ أَصۡحَٰبَ ٱلۡجَنَّةِ أَنۡ أَفِيضُواْ عَلَيۡنَا مِنَ ٱلۡمَآءِ أَوۡ مِمَّا رَزَقَكُمُ ٱللَّهُۚ قَالُوٓاْ إِنَّ ٱللَّهَ حَرَّمَهُمَا عَلَى ٱلۡكَٰفِرِينَ ٥٠","ونادى أصحاب النار أصحاب الجنة أن أفيضوا علينا من الماء أو مما رزقكم الله قالوا إن الله حرمهما على الكافرين","ނަރަކައިގެ އަހުލުވެރިން، ސުވަރުގޭގެ އަހުލުވެރިންނަށް ގޮވައި ބުނާނެތެވެ. ތިމަންމެންނަށް ފެންފޮދަކުން، ނުވަތަ ﷲ، ތިޔަބައިމީހުންނަށް ރިޒްގުކުރެއްވި އެއްޗަކުން އެހީވާށެވެ! އެއުރެން ބުނާނެތެވެ. އެތަކެތި ވަނީ، ކާފިރުވި މީހުންނަށް ﷲ، ހަރާމްކުރައްވާފައެވެ.","",""],["₇ سورة الأعراف","51","ٱلَّذِينَ ٱتَّخَذُواْ دِينَهُمۡ لَهۡوٗا وَلَعِبٗا وَغَرَّتۡهُمُ ٱلۡحَيَوٰةُ ٱلدُّنۡيَاۚ فَٱلۡيَوۡمَ نَنسَىٰهُمۡ كَمَا نَسُواْ لِقَآءَ يَوۡمِهِمۡ هَٰذَا وَمَا كَانُواْ بِـَٔايَٰتِنَا يَجۡحَدُونَ ٥١","الذين اتخذوا دينهم لهوا ولعبا وغرتهم الحياة الدنيا فاليوم ننساهم كما نسوا لقاء يومهم هذا وما كانوا بآياتنا يجحدون","އެއުރެންނީ، އެއުރެންގެ ދީން، ފޫހިފިލުވުމެއް ކަމުގައްޔާއި، ކުޅިވަރެއް ކަމުގައި ހަދައި، ދުނިޔޭގެ ދިރިއުޅުން އެއުރެން ހެއްލުންތެރިކޮށްފައިވާ މީހުންނެވެ. ފަހެ، އެއުރެން މިދުވަހާ ބައްދަލުވާނެކަން ހަނދާން ނައްތާލި ފަދައިން، އަދި ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާ ދެކޮޅު ހަދައި އުޅުނުކަމަށްޓަކައި އަދު ތިމަންރަސްކަލާނގެ އެއުރެންގެ މަތީން ހަނދުމަނެތި ކުރައްވާ ހުށީމެވެ.","",""],["₇ سورة الأعراف","52","وَلَقَدۡ جِئۡنَٰهُم بِكِتَٰبٖ فَصَّلۡنَٰهُ عَلَىٰ عِلۡمٍ هُدٗى وَرَحۡمَةٗ لِّقَوۡمٖ يُؤۡمِنُونَ ٥٢","ولقد جئناهم بكتاب فصلناه على علم هدى ورحمة لقوم يؤمنون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ފޮތެއް ދެއްވައި، ދެނެވޮޑިގަތުމާއެކު، ތިމަންރަސްކަލާނގެ އެ ފޮތް ތަފްޞީލު ކޮށް ބަޔާންކޮށްދެއްވީމެވެ. އެއީ އީމާންވާ ބަޔަކަށް ތެދުމަގެއް ކަމުގައްޔާއި، ރަހުމަތެއް ކަމުގައެވެ.","",""],["₇ سورة الأعراف","53","هَلۡ يَنظُرُونَ إِلَّا تَأۡوِيلَهُۥۚ يَوۡمَ يَأۡتِي تَأۡوِيلُهُۥ يَقُولُ ٱلَّذِينَ نَسُوهُ مِن قَبۡلُ قَدۡ جَآءَتۡ رُسُلُ رَبِّنَا بِٱلۡحَقِّ فَهَل لَّنَا مِن شُفَعَآءَ فَيَشۡفَعُواْ لَنَآ أَوۡ نُرَدُّ فَنَعۡمَلَ غَيۡرَ ٱلَّذِي كُنَّا نَعۡمَلُۚ قَدۡ خَسِرُوٓاْ أَنفُسَهُمۡ وَضَلَّ عَنۡهُم مَّا كَانُواْ يَفۡتَرُونَ ٥٣","هل ينظرون إلا تأويله يوم يأتي تأويله يقول الذين نسوه من قبل قد جاءت رسل ربنا بالحق فهل لنا من شفعاء فيشفعوا لنا أو نرد فنعمل غير الذي كنا نعمل قد خسروا أنفسهم وضل عنهم ما كانوا يفترون","އެންމެފަހުގެ ނަތީޖާއަށް މެނުވީ، އެއުރެން އިންތިޒާރުކުރޭހެއްޔެވެ؟ އެންމެފަހުގެ ނަތީޖާ (ފެނިގެން) އަންނަ ދުވަހު (އެބަހީ: ގިޔާމަތް ދުވަހު) ކުރިން އެކަންތައް ހަނދާން ނައްތާލި މީހުން ބުނާނެތެވެ. ހަމަކަށަވަރުން، ތިމަންމެންގެ ވެރިރަސްކަލާނގެ ފޮނުއްވި ރަސޫލުން، ހައްގު ދީނާއިގެން ވަޑައިގަތެވެ. ފަހެ، ތިމަންމެންނަށް ޝަފާއަތް ތެރިންތަކެއް ވޭބާވައެވެ؟ ނުވަތަ (ދުނިޔޭގައި) ތިމަންމެން ޢަމަލު ކޮށް އުޅުނުގޮތް ނޫންގޮތަކަށް ޢަމަލުކުރުމަށްޓަކައި، ތިމަންމެން އެނބުރި (ދުނިޔެއަށް) ފޮނުއްވާނެ ބާވައެވެ؟ ހަމަކަށަވަރުން، އެއުރެން، އެއުރެންގެ ނަފްސުތައް ނަގާލައިފިއެވެ. އަދި އެއުރެން ދޮގުން އުފައްދައި އުޅުނު އިލާހު ންތައް، އެއުރެންނަށް ގެއްލިހިނގައްޖެއެވެ.","",""],["₇ سورة الأعراف","54","إِنَّ رَبَّكُمُ ٱللَّهُ ٱلَّذِي خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضَ فِي سِتَّةِ أَيَّامٖ ثُمَّ ٱسۡتَوَىٰ عَلَى ٱلۡعَرۡشِۖ يُغۡشِي ٱلَّيۡلَ ٱلنَّهَارَ يَطۡلُبُهُۥ حَثِيثٗا وَٱلشَّمۡسَ وَٱلۡقَمَرَ وَٱلنُّجُومَ مُسَخَّرَٰتِۭ بِأَمۡرِهِۦٓۗ أَلَا لَهُ ٱلۡخَلۡقُ وَٱلۡأَمۡرُۗ تَبَارَكَ ٱللَّهُ رَبُّ ٱلۡعَٰلَمِينَ ٥٤","إن ربكم الله الذي خلق السماوات والأرض في ستة أيام ثم استوى على العرش يغشي الليل النهار يطلبه حثيثا والشمس والقمر والنجوم مسخرات بأمره ألا له الخلق والأمر تبارك الله رب العالمين","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއީ، ހަ ދުވަހުގެ ތެރޭގައި، އުޑުތަކާއި ބިން ހެއްދެވި ﷲއެވެ. އެއަށްފަހު، އެކަލާނގެ ޢަރްޝުގެ މައްޗަށް އިސްތިވާވެ ވޮޑިގެންވިއެވެ. އަދި އެކަލާނގެ ރޭގަނޑުން ދުވާލު ފޮރުއްވާލައްވައެވެ. (އެއިން ކޮންމެ އެއްޗެއް) އަވަސްކަމާއެކު (އަނެކައްޗެއް) ހޯދައިގަނެއެވެ. އަދި އިރާއި، ހަނދާއި، ތަރިތައް، އެކަލާނގެ އަމުރު ފުޅަށް ކިޔަމަން ކުރައްވާފައިވާ ގޮތުގައި ހެއްދެވިއެވެ. ދަންނާށެވެ! ހެއްދެވުމާއި އަމުރުކުރެއްވުންވަނީ، އެކަލާނގެއަށް ހާއްސަ ވެގެންނެވެ. އާލަމްތަކުގެ ވެރި ﷲ މަތިވެރިވެ ވޮޑިގެންފިއެވެ.","",""],["₇ سورة الأعراف","55","ٱدۡعُواْ رَبَّكُمۡ تَضَرُّعٗا وَخُفۡيَةًۚ إِنَّهُۥ لَا يُحِبُّ ٱلۡمُعۡتَدِينَ ٥٥","ادعوا ربكم تضرعا وخفية إنه لا يحب المعتدين","މަޑުމޮޅިކަމާއި، ވަންހަނާ ގޮތުގައި، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއަށް ދުއާކުރާށެވެ! ހަމަކަށަވަރުން، ހައްދުފަހަނަޅައިދާ މީހުންދެކެ އެކަލާނގެ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["₇ سورة الأعراف","56","وَلَا تُفۡسِدُواْ فِي ٱلۡأَرۡضِ بَعۡدَ إِصۡلَٰحِهَا وَٱدۡعُوهُ خَوۡفٗا وَطَمَعًاۚ إِنَّ رَحۡمَتَ ٱللَّهِ قَرِيبٞ مِّنَ ٱلۡمُحۡسِنِينَ ٥٦","ولا تفسدوا في الأرض بعد إصلاحها وادعوه خوفا وطمعا إن رحمت الله قريب من المحسنين","ބިން އިސްލާހުކުރެއްވުމަށްފަހު، ތިޔަބައިމީހުން އެ ބިމުގައި ފަސާދަ ނުކުރާށެވެ! އަދި ބިރުވެތިވެ، އެދުންވެ ތިބޭ ޙާލު، އެކަލާނގެއަށް ތިޔަބައިމީހުން ދުއާކުރާށެވެ! ހަމަކަށަވަރުން، ﷲގެ ރަހުމަތް ފުޅުވަނީ، އިހްސާން ތެރިންނާ ގާތުގައެވެ.","",""],["₇ سورة الأعراف","57","وَهُوَ ٱلَّذِي يُرۡسِلُ ٱلرِّيَٰحَ بُشۡرَۢا بَيۡنَ يَدَيۡ رَحۡمَتِهِۦۖ حَتَّىٰٓ إِذَآ أَقَلَّتۡ سَحَابٗا ثِقَالٗا سُقۡنَٰهُ لِبَلَدٖ مَّيِّتٖ فَأَنزَلۡنَا بِهِ ٱلۡمَآءَ فَأَخۡرَجۡنَا بِهِۦ مِن كُلِّ ٱلثَّمَرَٰتِۚ كَذَٰلِكَ نُخۡرِجُ ٱلۡمَوۡتَىٰ لَعَلَّكُمۡ تَذَكَّرُونَ ٥٧","وهو الذي يرسل الرياح بشرا بين يدي رحمته حتى إذا أقلت سحابا ثقالا سقناه لبلد ميت فأنزلنا به الماء فأخرجنا به من كل الثمرات كذلك نخرج الموتى لعلكم تذكرون","އަދި އެކަލާނގެ ރަހުމަތްގެ ކުރިޔަށް، (އެބަހީ: ވާރޭގެ ކުރިޔަށް) އުފާވެރި ޚަބަރެއްގެ ގޮތުގައި، ވައިރޯޅިތައް ފޮނުއްވަނީ އެކަލާނގެއެވެ. އަދި އެ ރޯޅިތައް، ފެނުން ބަރުވެފައިވާ ވިލާގަނޑެއް އުފުލައިގަތުމުން، މަރުވެފައިވާ ރަށަކަށް ތިމަންރަސްކަލާނގެ އެ ވިލާގަނޑު ފޮނުއްވަމެވެ. ދެން އެއިން ފެންވެއްސަވައި، ހުރިހާ ބާވަތެއްގެ މޭވާއިން ގަސް ފަޅުއްވަމެވެ. މަރުވެފައިވާ މީހުން (އަލުން ދިރުއްވައި) ނެރުއްވާހުށީ، ހަމައެފަދައިންނެވެ. (އެއީ) ތިޔަބައިމީހުން ހަނދުމަ ކުރުމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","58","وَٱلۡبَلَدُ ٱلطَّيِّبُ يَخۡرُجُ نَبَاتُهُۥ بِإِذۡنِ رَبِّهِۦۖ وَٱلَّذِي خَبُثَ لَا يَخۡرُجُ إِلَّا نَكِدٗاۚ كَذَٰلِكَ نُصَرِّفُ ٱلۡأٓيَٰتِ لِقَوۡمٖ يَشۡكُرُونَ ٥٨","والبلد الطيب يخرج نباته بإذن ربه والذي خبث لا يخرج إلا نكدا كذلك نصرف الآيات لقوم يشكرون","(ބިމާއި ފެން) ރަނގަޅު ރަށްރަށުން، އެރަށްތަކުގެ ވެރިރަސްކަލާނގެ އިޒުނަ ފުޅާއެކު، އެރަށުގެ ގަސްގަހާގެހި ފަޅައެވެ. (ބިން) ނުބައި ރަށްރަށުން ފައިދާއެއްނެތް މަދު ގަސްކޮޅެއް މެނުވީ ނުފަޅައެވެ. ޝުކުރުކުރާ ބަޔަކަށް ތިމަންރަސްކަލާނގެ އާޔަތްތައް އެކިގޮތްގޮތަށް ބަޔާންކޮށްދެއްވަނީ އެފަދައިންނެވެ.","",""],["₇ سورة الأعراف","59","لَقَدۡ أَرۡسَلۡنَا نُوحًا إِلَىٰ قَوۡمِهِۦ فَقَالَ يَٰقَوۡمِ ٱعۡبُدُواْ ٱللَّهَ مَا لَكُم مِّنۡ إِلَٰهٍ غَيۡرُهُۥٓ إِنِّيٓ أَخَافُ عَلَيۡكُمۡ عَذَابَ يَوۡمٍ عَظِيمٖ ٥٩","لقد أرسلنا نوحا إلى قومه فقال يا قوم اعبدوا الله ما لكم من إله غيره إني أخاف عليكم عذاب يوم عظيم","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ނޫޙުގެފާނު، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ގާތަށް ރަސޫލުކަމާއިގެން ފޮނުއްވީމެވެ. ފަހެ، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން ﷲއަށް އަޅުކަން ކުރާށެވެ! އެކަލާނގެ ފިޔަވައި އެހެން އިލާހަކު ތިޔަބައިމީހުންނަކަށް ނުވެތެވެ. ހަމަކަށަވަރުން، ބޮޑުވެގެންވާ ދުވަހެއްގެ އަޒާބު ތިޔަބައިމީހުންނަށް ލިބިދާނެކަމަށް އަހުރެން ބިރުގަނެއެވެ.","",""],["₇ سورة الأعراف","60","قَالَ ٱلۡمَلَأُ مِن قَوۡمِهِۦٓ إِنَّا لَنَرَىٰكَ فِي ضَلَٰلٖ مُّبِينٖ ٦٠","قال الملأ من قومه إنا لنراك في ضلال مبين","އެކަލޭގެފާނުގެ ގައުމުގެބޮޑުން ބުނޫއެވެ. ހަމަކަށަވަރުން، އަހުރެމެންނަށް ފެންނަނީ، ފާޅުވެގެންވާ ފުރެދުމެއްގައި ކަލޭގެފާނު ވާތީއެވެ.","",""],["₇ سورة الأعراف","61","قَالَ يَٰقَوۡمِ لَيۡسَ بِي ضَلَٰلَةٞ وَلَٰكِنِّي رَسُولٞ مِّن رَّبِّ ٱلۡعَٰلَمِينَ ٦١","قال يا قوم ليس بي ضلالة ولكني رسول من رب العالمين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! އަހުރެންގެ ކިބައިގައި އެއްވެސް ފުރެދުމެއް ނެތެވެ. އަދި ކީއްހެއްޔެވެ؟ އަހުރެންނީ، އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައި ރަސޫލަކީމެވެ.","",""],["₇ سورة الأعراف","62","أُبَلِّغُكُمۡ رِسَٰلَٰتِ رَبِّي وَأَنصَحُ لَكُمۡ وَأَعۡلَمُ مِنَ ٱللَّهِ مَا لَا تَعۡلَمُونَ ٦٢","أبلغكم رسالات ربي وأنصح لكم وأعلم من الله ما لا تعلمون","އަހުރެންގެ ވެރިރަސްކަލާނގެ ރަސޫލު ކަން ތިޔަބައިމީހުންނަށް އަހުރެން އިއްވަމެވެ. އަދި ތިޔަބައިމީހުންނަށް ނަސޭހަތް ތެރިވަމެވެ. އަދި ތިޔަބައިމީހުންނަށް ނޭނގޭ ކަންތައްތައް ﷲގެ ހަޒުރަތުން އަހުރެންނަށް އެނގެއެވެ.","",""],["₇ سورة الأعراف","63","أَوَعَجِبۡتُمۡ أَن جَآءَكُمۡ ذِكۡرٞ مِّن رَّبِّكُمۡ عَلَىٰ رَجُلٖ مِّنكُمۡ لِيُنذِرَكُمۡ وَلِتَتَّقُواْ وَلَعَلَّكُمۡ تُرۡحَمُونَ ٦٣","أوعجبتم أن جاءكم ذكر من ربكم على رجل منكم لينذركم ولتتقوا ولعلكم ترحمون","ތިޔަބައިމީހުންނަށް އިންޒާރުކުރެއްވުމަށާއި، ތިޔަބައިމީހުން ތަގުވާވެރިވުމަށާއި، ތިޔަބައިމީހުންނަށް ރަހުމަތް ލައްވާތޯ، ތިޔަބައިމީހުންގެ ތެރެއިން ފިރިހެނަކު މެދުވެރިކޮށް، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ހަނދާން ކޮށްދިނުމެއް ތިޔަބައިމީހުންނަށް އައިކަމަށްޓަކައި، ތިޔަބައިމީހުން ހައިރާން ވީހެއްޔެވެ؟","",""],["₇ سورة الأعراف","64","فَكَذَّبُوهُ فَأَنجَيۡنَٰهُ وَٱلَّذِينَ مَعَهُۥ فِي ٱلۡفُلۡكِ وَأَغۡرَقۡنَا ٱلَّذِينَ كَذَّبُواْ بِـَٔايَٰتِنَآۚ إِنَّهُمۡ كَانُواْ قَوۡمًا عَمِينَ ٦٤","فكذبوه فأنجيناه والذين معه في الفلك وأغرقنا الذين كذبوا بآياتنا إنهم كانوا قوما عمين","ފަހެ، އެއުރެން އެކަލޭގެފާނު ދޮގުކުރޫއެވެ. ދެން ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނާއި، އެކަލޭގެފާނުގެ އަރިހުގައި ނާކޮޅުގައިވާ އެންމެން ސަލާމަތް ކުރެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުރި މީހުން ޣަރަގުކުރެއްވީމެވެ. ހަމަކަށަވަރުން، އެމީހުންވީ (ހައްގުގެ މަގު ނުފެންނަ) ކަނު ބަޔަކު ކަމުގައެވެ.","",""],["₇ سورة الأعراف","65","۞وَإِلَىٰ عَادٍ أَخَاهُمۡ هُودٗاۚ قَالَ يَٰقَوۡمِ ٱعۡبُدُواْ ٱللَّهَ مَا لَكُم مِّنۡ إِلَٰهٍ غَيۡرُهُۥٓۚ أَفَلَا تَتَّقُونَ ٦٥","وإلى عاد أخاهم هودا قال يا قوم اعبدوا الله ما لكم من إله غيره أفلا تتقون","އަދި ތިމަންރަސްކަލާނގެ ޢާދު ބާގައިމީހުންގެ ގާތަށް އެއުރެންގެ އަޚު، ހޫދުގެފާނު (ފޮނުއްވީމެވެ.) އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން ﷲއަށް އަޅުކަން ކުރާށެވެ! އެކަލާނގެ ފިޔަވައި، އެހެން އިލާހަކު ތިޔަބައިމީހުންނަކަށް ނުވެއެވެ. ފަހެ، ތިޔަބައިމީހުން (އެކަލާނގެއަށް) ތަގުވާވެރި ނުވަނީ ހެއްޔެވެ؟","",""],["₇ سورة الأعراف","66","قَالَ ٱلۡمَلَأُ ٱلَّذِينَ كَفَرُواْ مِن قَوۡمِهِۦٓ إِنَّا لَنَرَىٰكَ فِي سَفَاهَةٖ وَإِنَّا لَنَظُنُّكَ مِنَ ٱلۡكَٰذِبِينَ ٦٦","قال الملأ الذين كفروا من قومه إنا لنراك في سفاهة وإنا لنظنك من الكاذبين","އެކަލޭގެފާނުގެ ގައުމުގެމީހުންކުރެ ކާފިރުވި ބޮޑުން ބުނޫއެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުވަނީ، މޮޔަކަމެއްގެތެރޭގައިކަމަށް ތިމަންމެންނަށް ފެނެއެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންމެންނަށް ހީވަނީ، ކަލޭގެފާނަކީ، ދޮގުވެރިންގެ ތެރެއިންވާ މީހެއް ކަމުގައެވެ.","",""],["₇ سورة الأعراف","67","قَالَ يَٰقَوۡمِ لَيۡسَ بِي سَفَاهَةٞ وَلَٰكِنِّي رَسُولٞ مِّن رَّبِّ ٱلۡعَٰلَمِينَ ٦٧","قال يا قوم ليس بي سفاهة ولكني رسول من رب العالمين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! އަހުރެންގެ ކިބައިގައި އެއްވެސް މޮޔަކަމެއް ނެތެވެ. އަދި ކީއްހެއްޔެވެ؟ އަހުރެންނީ، އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައި ރަސޫލަކީމެވެ.","",""],["₇ سورة الأعراف","68","أُبَلِّغُكُمۡ رِسَٰلَٰتِ رَبِّي وَأَنَا۠ لَكُمۡ نَاصِحٌ أَمِينٌ ٦٨","أبلغكم رسالات ربي وأنا لكم ناصح أمين","އަހުރެންގެ ވެރިރަސްކަލާނގެ ރަސޫލު ކަން ތިޔަބައިމީހުންނަށް އަހުރެން އިއްވަމެވެ. އަދި އަހުރެންނީ، ތިޔަބައިމީހުންނަށްވާ އަމާނަތް ތެރި ނަސޭހަތް ތެރިޔަކީމެވެ.","",""],["₇ سورة الأعراف","69","أَوَعَجِبۡتُمۡ أَن جَآءَكُمۡ ذِكۡرٞ مِّن رَّبِّكُمۡ عَلَىٰ رَجُلٖ مِّنكُمۡ لِيُنذِرَكُمۡۚ وَٱذۡكُرُوٓاْ إِذۡ جَعَلَكُمۡ خُلَفَآءَ مِنۢ بَعۡدِ قَوۡمِ نُوحٖ وَزَادَكُمۡ فِي ٱلۡخَلۡقِ بَصۜۡطَةٗۖ فَٱذۡكُرُوٓاْ ءَالَآءَ ٱللَّهِ لَعَلَّكُمۡ تُفۡلِحُونَ ٦٩","أوعجبتم أن جاءكم ذكر من ربكم على رجل منكم لينذركم واذكروا إذ جعلكم خلفاء من بعد قوم نوح وزادكم في الخلق بسطة فاذكروا آلاء الله لعلكم تفلحون","ތިޔަބައިމީހުންނަށް އިންޒާރުކުރެއްވުމަށް، ތިޔަބައިމީހުންގެ ތެރެއިން ފިރިހެނަކު މެދުވެރިކޮށް، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ހަނދާން ކޮށްދިނުމެއް، ތިޔަބައިމީހުންނަށް އައިކަމަށްޓަކައި، ތިޔަބައިމީހުން ހައިރާން ވީހެއްޔެވެ؟ އަދި ނޫޙުގެފާނުގެ ގައުމަށްފަހުގައި، ޚަލީފާ އިން ކަމުގައި ތިޔަބައިމީހުން ލެއްވިކަމާއި، ހެއްދެވުމުގައި ތިޔަބައިމީހުންގެ އިސްކޮޅާއި ބާރު އިތުރުކުރެއްވިކަން ތިޔަބައިމީހުން ހަނދުމަކުރާށެވެ! ފަހެ، ﷲގެ ނިއުމަތްތައް ތިޔަބައިމީހުން ހަނދުމަކުރާށެވެ! (އެއީ) ތިޔަބައިމީހުން ދިންނަވައި ނަސީބު ލިބުމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","70","قَالُوٓاْ أَجِئۡتَنَا لِنَعۡبُدَ ٱللَّهَ وَحۡدَهُۥ وَنَذَرَ مَا كَانَ يَعۡبُدُ ءَابَآؤُنَا فَأۡتِنَا بِمَا تَعِدُنَآ إِن كُنتَ مِنَ ٱلصَّـٰدِقِينَ ٧٠","قالوا أجئتنا لنعبد الله وحده ونذر ما كان يعبد آباؤنا فأتنا بما تعدنا إن كنت من الصادقين","އެއުރެން ބުނޫއެވެ. ކަލޭގެފާނު އަހުރެމެންގެ ގާތަށް ތިޔަވަޑައިގަތީ، ހަމައެކަނި ﷲއަށް އަހުރެމެން އަޅުކަން ކުރުމަށާއި، އަހުރެމެންގެ ކާބަފައިން އަޅުކަންކޮށް އުޅުނު ތަކެތި އަހުރެމެން ދޫކޮށްލުމަށް އެންގެވުމަށްތޯއެވެ؟ ފަހެ، ކަލޭގެފާނުވަނީ، ތެދުވެރިންގެ ތެރެއިން ކަމަށްވާނަމަ، ކަލޭގެފާނު އަހުރެމެންނަށް ތިޔަ ވައުދުކުރައްވާ ކަމެއް، އަހުރެމެން ގާތަށް ނިކަން ގެންނަވައި ބައްލަވާށެވެ!","",""],["₇ سورة الأعراف","71","قَالَ قَدۡ وَقَعَ عَلَيۡكُم مِّن رَّبِّكُمۡ رِجۡسٞ وَغَضَبٌۖ أَتُجَٰدِلُونَنِي فِيٓ أَسۡمَآءٖ سَمَّيۡتُمُوهَآ أَنتُمۡ وَءَابَآؤُكُم مَّا نَزَّلَ ٱللَّهُ بِهَا مِن سُلۡطَٰنٖۚ فَٱنتَظِرُوٓاْ إِنِّي مَعَكُم مِّنَ ٱلۡمُنتَظِرِينَ ٧١","قال قد وقع عليكم من ربكم رجس وغضب أتجادلونني في أسماء سميتموها أنتم وآباؤكم ما نزل الله بها من سلطان فانتظروا إني معكم من المنتظرين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އަޒާބަކާއި، ކޯފާއެއް އައިސް، ތިޔަބައިމީހުންގެ މައްޗަށް ހުށަހެޅިއްޖެކަން ކަށަވަރެވެ. ތިޔަބައިމީހުންނާއި، ތިޔަބައިމީހުންގެ ކާބަފައިން، ނަންދީފައިވާ ބުދުތަކާމެދު، ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނާ ޖަދަލުކުރަނީ ހެއްޔެވެ؟ އެތަކެއްޗަށް (އަޅުކަން ކުރުމަށް) އެއްވެސް ހުއްޖަތެއް ﷲ ބާވައެއް ނުލައްވަތެވެ. ފަހެ، ތިޔަބައިމީހުން އިންތިޒާރުކުރާށެވެ! ތިމަންކަލޭގެފާނުވެސް ތިޔަބައިމީހުންނާއެކު އިންތިޒާރުކުރާ މީހުންގެ ތެރެއިން ވާހުށީމެވެ.","",""],["₇ سورة الأعراف","72","فَأَنجَيۡنَٰهُ وَٱلَّذِينَ مَعَهُۥ بِرَحۡمَةٖ مِّنَّا وَقَطَعۡنَا دَابِرَ ٱلَّذِينَ كَذَّبُواْ بِـَٔايَٰتِنَاۖ وَمَا كَانُواْ مُؤۡمِنِينَ ٧٢","فأنجيناه والذين معه برحمة منا وقطعنا دابر الذين كذبوا بآياتنا وما كانوا مؤمنين","ދެން (ތިމަންރަސްކަލާނގެ ކޯފާއާއި، އަޒާބު އައިހިނދު) ތިމަންރަސްކަލާނގެ ރަހުމަތްފުޅުން، އެކަލޭގެފާނާއި، އެކަލޭގެފާނުގެ އަރިހުގައިވާ ބަޔަކު، ތިމަންރަސްކަލާނގެ ސަލާމަތްކުރެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުޅަ މީހުންގެ އެންމެފަހު މީހާއަށް ދާނދެން، ހަލާކު ކުރައްވައި، ނެތިކުރެއްވީމެވެ. އަދި އެއުރެން އީމާންވި ބަޔަކު ކަމުގައި ނުވެތެވެ.","",""],["₇ سورة الأعراف","73","وَإِلَىٰ ثَمُودَ أَخَاهُمۡ صَٰلِحٗاۚ قَالَ يَٰقَوۡمِ ٱعۡبُدُواْ ٱللَّهَ مَا لَكُم مِّنۡ إِلَٰهٍ غَيۡرُهُۥۖ قَدۡ جَآءَتۡكُم بَيِّنَةٞ مِّن رَّبِّكُمۡۖ هَٰذِهِۦ نَاقَةُ ٱللَّهِ لَكُمۡ ءَايَةٗۖ فَذَرُوهَا تَأۡكُلۡ فِيٓ أَرۡضِ ٱللَّهِۖ وَلَا تَمَسُّوهَا بِسُوٓءٖ فَيَأۡخُذَكُمۡ عَذَابٌ أَلِيمٞ ٧٣","وإلى ثمود أخاهم صالحا قال يا قوم اعبدوا الله ما لكم من إله غيره قد جاءتكم بينة من ربكم هذه ناقة الله لكم آية فذروها تأكل في أرض الله ولا تمسوها بسوء فيأخذكم عذاب أليم","އަދި ތިމަންރަސްކަލާނގެ ޘަމޫދު ބާގައިމީހުންގެ ގާތަށް އެއުރެންގެ އަޚު، ސާލިހުގެފާނު (ފޮނުއްވީމެވެ.) އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން، ﷲއަށް އަޅުކަންކުރާށެވެ! އެކަލާނގެ ފިޔަވައި، އެހެން އިލާހަކު ތިޔަބައިމީހުންނަކަށް ނުވެއެވެ. ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ބަޔާންވެގެންވާ މުއުޖިޒާއެއް ތިޔަބައިމީހުންނަށް އަތުވެއްޖެކަން ކަށަވަރެވެ. މުއުޖިޒާއެއްގެ ގޮތުން މިއޮތީ ތިޔަބައިމީހުންނަށްޓަކައި ﷲ ފޮނުއްވި ޖަމަލެވެ. ފަހެ، ﷲގެ ބިމުން އޭތި ކައިއުޅުމަށް ތިޔަބައިމީހުން ދޫކުރާށެވެ! އަދި އެއަށް އެއްވެސް ގޯނާއެއް ތިޔަބައިމީހުން ނުކުރާށެވެ! ފަހެ، (އެކަން ކޮށްފިނަމަ) ވޭންދެނިވި އަޒާބެއް ތިޔަބައިމީހުންނަށް ލިބޭނެތެވެ.","",""],["₇ سورة الأعراف","74","وَٱذۡكُرُوٓاْ إِذۡ جَعَلَكُمۡ خُلَفَآءَ مِنۢ بَعۡدِ عَادٖ وَبَوَّأَكُمۡ فِي ٱلۡأَرۡضِ تَتَّخِذُونَ مِن سُهُولِهَا قُصُورٗا وَتَنۡحِتُونَ ٱلۡجِبَالَ بُيُوتٗاۖ فَٱذۡكُرُوٓاْ ءَالَآءَ ٱللَّهِ وَلَا تَعۡثَوۡاْ فِي ٱلۡأَرۡضِ مُفۡسِدِينَ ٧٤","واذكروا إذ جعلكم خلفاء من بعد عاد وبوأكم في الأرض تتخذون من سهولها قصورا وتنحتون الجبال بيوتا فاذكروا آلاء الله ولا تعثوا في الأرض مفسدين","އަދި ޢާދު ބާގައިމީހުންގެ ފަހުން، ޚަލީފާ އިން ކަމުގައި އެކަލާނގެ ތިޔަބައިމީހުން ލެއްވިކަމާއި، ބިމުގައި ތިޔަބައިމީހުން ވަޒަންވެރި ކުރެއްވިކަން ހަނދުމަކުރާށެވެ! އެތާނގެ ހަމަބިންތަކުން ގަނޑުވަރުތައް ތިޔަބައިމީހުން ހަދަމުއެވެ. އަދި ފަރުބަދަތައް ކަނޑައިގެން، ގެތައްވެސް ތިޔަބައިމީހުން ހަދަމުއެވެ. ފަހެ، ﷲގެ ނިއުމަތްތައް ތިޔަބައިމީހުން ހަނދުމަކުރާށެވެ! އަދި ފާސިދުން ކަމުގައިވެތިބެ، ތިޔަބައިމީހުން ބިމުގައި ފަސާދަ ނުކުރާހުށިކަމެވެ!","",""],["₇ سورة الأعراف","75","قَالَ ٱلۡمَلَأُ ٱلَّذِينَ ٱسۡتَكۡبَرُواْ مِن قَوۡمِهِۦ لِلَّذِينَ ٱسۡتُضۡعِفُواْ لِمَنۡ ءَامَنَ مِنۡهُمۡ أَتَعۡلَمُونَ أَنَّ صَٰلِحٗا مُّرۡسَلٞ مِّن رَّبِّهِۦۚ قَالُوٓاْ إِنَّا بِمَآ أُرۡسِلَ بِهِۦ مُؤۡمِنُونَ ٧٥","قال الملأ الذين استكبروا من قومه للذين استضعفوا لمن آمن منهم أتعلمون أن صالحا مرسل من ربه قالوا إنا بما أرسل به مؤمنون","އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ތެރެއިން ކިބުރުވެރިވެގަތް ބޮޑުން، އޭގެތެރެއިން އީމާންވެ، ނިކަމެތިކޮށްހިތުނު މީހުންނަށް ބުނޫއެވެ. ސާލިހުގެފާނަކީ، އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ފޮނުއްވި ރަސޫލަކުކަން ތިޔަބައިމީހުން ދެނެތިބީމު ހެއްޔެވެ؟ އެއުރެން ބުނޫއެވެ. ހަމަކަށަވަރުން، އެކަލޭގެފާނު އެކަމަކާއިގެން ފޮނުއްވި ކަމަކަށް، ތިމަންމެން މިތިބީ އީމާންވެގެންނެވެ.","",""],["₇ سورة الأعراف","76","قَالَ ٱلَّذِينَ ٱسۡتَكۡبَرُوٓاْ إِنَّا بِٱلَّذِيٓ ءَامَنتُم بِهِۦ كَٰفِرُونَ ٧٦","قال الذين استكبروا إنا بالذي آمنتم به كافرون","ކިބުރުވެރިވިމީހުން ބުނޫއެވެ. ތިޔަބައިމީހުން، އީމާންވި ކަންތަކަށް ހަމަކަށަވަރުން، އަހުރެމެން މިތިބީ ކާފިރު ވެގެންނެވެ.","",""],["₇ سورة الأعراف","77","فَعَقَرُواْ ٱلنَّاقَةَ وَعَتَوۡاْ عَنۡ أَمۡرِ رَبِّهِمۡ وَقَالُواْ يَٰصَٰلِحُ ٱئۡتِنَا بِمَا تَعِدُنَآ إِن كُنتَ مِنَ ٱلۡمُرۡسَلِينَ ٧٧","فعقروا الناقة وعتوا عن أمر ربهم وقالوا يا صالح ائتنا بما تعدنا إن كنت من المرسلين","ފަހެ، އެއުރެން އެ ޖަމަލު މަރައިލޫއެވެ. އަދި އެއުރެންގެ ވެރިރަސްކަލާނގެ އަމުރުފުޅަށް ނުކިޔަމަންތެރިވޫއެވެ. އަދި އެއުރެން ބުނޫއެވެ. އޭ ސާލިހުގެފާނެވެ! ކަލޭގެފާނުވަނީ، ރަސޫލުންގެ ތެރެއިން ކަމަށްވާނަމަ، ކަލޭގެފާނު އަހުރެމެންނަށް ތިޔަ ވައުދުކުރައްވާ ކަމެއް (އެބަހީ: އަޒާބު) އަހުރެމެންނަށް ނިކަން ގެންނަވައި ބައްލަވާށެވެ!","",""],["₇ سورة الأعراف","78","فَأَخَذَتۡهُمُ ٱلرَّجۡفَةُ فَأَصۡبَحُواْ فِي دَارِهِمۡ جَٰثِمِينَ ٧٨","فأخذتهم الرجفة فأصبحوا في دارهم جاثمين","ދެންފަހެ، ބިރުވެރި ބިންހެލުމެއް އެއުރެންނަށް އައިސްޖެހުނެވެ. އަދި އެއުރެންގެ ގެތަކުގައި، ކަކޫމައްޗަށް ތިރިވެ، މަރުވެފައިތިބި ބަޔަކު ކަމުގައި އެއުރެން ވެއްޖައޫއެވެ.","",""],["₇ سورة الأعراف","79","فَتَوَلَّىٰ عَنۡهُمۡ وَقَالَ يَٰقَوۡمِ لَقَدۡ أَبۡلَغۡتُكُمۡ رِسَالَةَ رَبِّي وَنَصَحۡتُ لَكُمۡ وَلَٰكِن لَّا تُحِبُّونَ ٱلنَّـٰصِحِينَ ٧٩","فتولى عنهم وقال يا قوم لقد أبلغتكم رسالة ربي ونصحت لكم ولكن لا تحبون الناصحين","ދެން އެކަލޭގެފާނު، އެއުރެންގެ ކިބައިން ދުރުހެލިވެވަޑައިގަތެވެ. އަދި އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ހަމަކަށަވަރުން، އަހުރެންގެ ވެރިރަސްކަލާނގެ ރަސޫލު ކަން ތިޔަބައިމީހުންނަށް އިއްވީމެވެ. އަދި ތިޔަބައިމީހުންނަށް އަހުރެން ނަސޭހަތް ތެރިވީމެވެ. އެހެނެއްކަމަކު، ތިޔަބައިމީހުން ނަސޭހަތް ތެރިވާ މީހުންދެކެ ލޯތްބެއް ނުވަމުއެވެ.","",""],["₇ سورة الأعراف","80","وَلُوطًا إِذۡ قَالَ لِقَوۡمِهِۦٓ أَتَأۡتُونَ ٱلۡفَٰحِشَةَ مَا سَبَقَكُم بِهَا مِنۡ أَحَدٖ مِّنَ ٱلۡعَٰلَمِينَ ٨٠","ولوطا إذ قال لقومه أتأتون الفاحشة ما سبقكم بها من أحد من العالمين","އަދި ލޫޠުގެފާނު، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް ވިދާޅުވިހިނދު (ހަނދުމަކުރާށެވެ!) ތިޔަބައިމީހުންގެ ކުރިން، އާލަމްތަކުގެ ތެރެއިން އެކަކުވެސް ކޮށްފައިނުވާ ފާޙިޝް ޢަމަލު ތިޔަބައިމީހުން ކުރަނީހެއްޔެވެ؟","",""],["₇ سورة الأعراف","81","إِنَّكُمۡ لَتَأۡتُونَ ٱلرِّجَالَ شَهۡوَةٗ مِّن دُونِ ٱلنِّسَآءِۚ بَلۡ أَنتُمۡ قَوۡمٞ مُّسۡرِفُونَ ٨١","إنكم لتأتون الرجال شهوة من دون النساء بل أنتم قوم مسرفون","ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ޝަހްވާނީ ގޮތުން، އަންހެނުން ދޫކޮށް، ފިރިހެނުންނާ ގާތްވަމުއެވެ. އަދި ކިއެއްތަ! ތިޔަބައިމީހުންނީ (ފާފަކުރުމުގައި) ހައްދުފަހަނަޅައިފައިވާ ބަޔަކީމުއެވެ.","",""],["₇ سورة الأعراف","82","وَمَا كَانَ جَوَابَ قَوۡمِهِۦٓ إِلَّآ أَن قَالُوٓاْ أَخۡرِجُوهُم مِّن قَرۡيَتِكُمۡۖ إِنَّهُمۡ أُنَاسٞ يَتَطَهَّرُونَ ٨٢","وما كان جواب قومه إلا أن قالوا أخرجوهم من قريتكم إنهم أناس يتطهرون","އެކަލޭގެފާނުގެ (އެބަހީ: ލޫޠުގެފާނުގެ) ގައުމުގެމީހުންގެ ޖަވާބު ކަމުގައި އެއުރެންގެ މި ބުނުން ނޫނީ ނުވެތެވެ. ތިޔަބައިމީހުންގެ ރަށުން، އެއުރެން (އެބަހީ: ލޫޠުގެފާނާއި، އެކަލޭގެފާނަށް އީމާން ވެގެން ތިބިމީހުން) ބޭރުކޮށްލާށެވެ! ހަމަކަށަވަރުން، އެއުރެންނަކީ، ތާހިރު ވެގަންނަ ބަޔެކެވެ.","",""],["₇ سورة الأعراف","83","فَأَنجَيۡنَٰهُ وَأَهۡلَهُۥٓ إِلَّا ٱمۡرَأَتَهُۥ كَانَتۡ مِنَ ٱلۡغَٰبِرِينَ ٨٣","فأنجيناه وأهله إلا امرأته كانت من الغابرين","ފަހެ، އެކަލޭގެފާނުގެ އަނބިކަނބަލުން ފިޔަވައި، އެކަލޭގެފާނާއި، އެކަލޭގެފާނުގެ އަހުލުވެރިން، ތިމަންރަސްކަލާނގެ ސަލާމަތްކުރެއްވީމެވެ. އެކަނބުލޭގެވީ، ހަލާކުވެދިޔަ މީހުންގެ ތެރެއިންނެވެ.","",""],["₇ سورة الأعراف","84","وَأَمۡطَرۡنَا عَلَيۡهِم مَّطَرٗاۖ فَٱنظُرۡ كَيۡفَ كَانَ عَٰقِبَةُ ٱلۡمُجۡرِمِينَ ٨٤","وأمطرنا عليهم مطرا فانظر كيف كان عاقبة المجرمين","އަދި ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް (ހިލައިގެ) ވާރެއެއް ވެއްސެވީމެވެ. ފަހެ، ކުށްވެރިންގެ ނިމުންހުރީ ކިހިނަކުންކަން، ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާށެވެ!","",""],["₇ سورة الأعراف","85","وَإِلَىٰ مَدۡيَنَ أَخَاهُمۡ شُعَيۡبٗاۚ قَالَ يَٰقَوۡمِ ٱعۡبُدُواْ ٱللَّهَ مَا لَكُم مِّنۡ إِلَٰهٍ غَيۡرُهُۥۖ قَدۡ جَآءَتۡكُم بَيِّنَةٞ مِّن رَّبِّكُمۡۖ فَأَوۡفُواْ ٱلۡكَيۡلَ وَٱلۡمِيزَانَ وَلَا تَبۡخَسُواْ ٱلنَّاسَ أَشۡيَآءَهُمۡ وَلَا تُفۡسِدُواْ فِي ٱلۡأَرۡضِ بَعۡدَ إِصۡلَٰحِهَاۚ ذَٰلِكُمۡ خَيۡرٞ لَّكُمۡ إِن كُنتُم مُّؤۡمِنِينَ ٨٥","وإلى مدين أخاهم شعيبا قال يا قوم اعبدوا الله ما لكم من إله غيره قد جاءتكم بينة من ربكم فأوفوا الكيل والميزان ولا تبخسوا الناس أشياءهم ولا تفسدوا في الأرض بعد إصلاحها ذلكم خير لكم إن كنتم مؤمنين","އަދި މަދްޔަންގެމީހުންގެ ގާތަށް ތިމަންރަސްކަލާނގެ އެއުރެންގެ އަޚު، ޝުއައިބުގެފާނު (ފޮނުއްވީމެވެ.) އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން، ﷲއަށް އަޅުކަން ކުރާށެވެ! އެކަލާނގެ ފިޔަވައި، އެހެން އިލާހަކު ތިޔަބައިމީހުންނަކަށް ނުވެތެވެ. ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން، ބަޔާންވެގެންވާ ހެތްކެއް ތިޔަބައިމީހުންނަށް އަތުވެއްޖެކަން ކަށަވަރެވެ. ފަހެ، ތިޔަބައިމީހުން، މިނުމާއި، ކިރުން ފުރިހަމަ ކުރާށެވެ! އަދި މީސްތަކުންނަށް އެއުރެންގެ ތަކެތި ތިޔަބައިމީހުން އުނިނުކުރާށެވެ! އަދި އެ ބިން އިސްލާހުކުރުމަށްފަހު، ތިޔަބައިމީހުން ބިމުގައި ފަސާދަ ނުކުރާށެވެ! ތިޔަބައިމީހުންނީ، އީމާންވާ ބަޔަކު ކަމުގައިވާނަމަ، އެގޮތް ތިޔަބައިމީހުންނަށް ހެޔޮކަން ބޮޑެވެ.","",""],["₇ سورة الأعراف","86","وَلَا تَقۡعُدُواْ بِكُلِّ صِرَٰطٖ تُوعِدُونَ وَتَصُدُّونَ عَن سَبِيلِ ٱللَّهِ مَنۡ ءَامَنَ بِهِۦ وَتَبۡغُونَهَا عِوَجٗاۚ وَٱذۡكُرُوٓاْ إِذۡ كُنتُمۡ قَلِيلٗا فَكَثَّرَكُمۡۖ وَٱنظُرُواْ كَيۡفَ كَانَ عَٰقِبَةُ ٱلۡمُفۡسِدِينَ ٨٦","ولا تقعدوا بكل صراط توعدون وتصدون عن سبيل الله من آمن به وتبغونها عوجا واذكروا إذ كنتم قليلا فكثركم وانظروا كيف كان عاقبة المفسدين","އަދި ބިރުދައްކައި، ފޭރުމަށާއި، ﷲއަށް އީމާންވި މީހުން އެކަލާނގެ މަގުން އެއްކިބާކުރުމަށާއި، އެމަގު ގުދުމަގަކަށް ހެދުމަށް އެދި، އެއްވެސް މަގެއްގައި ތިޔަބައިމީހުން ނުތިބޭށެވެ! އަދި ތިޔަބައިމީހުން، މަދުބަޔަކު ކަމުގައި ތިއްބައި އެކަލާނގެ، ތިޔަބައިމީހުން ގިނަކުރެއްވިކަން ހަނދުމަކުރާށެވެ! އަދި ފަސާދަކުރާ މީހުންގެ ނިމުންހުރީ ކިހިނަކުންކަން، ތިޔަބައިމީހުން ދެކޭށެވެ!","",""],["₇ سورة الأعراف","87","وَإِن كَانَ طَآئِفَةٞ مِّنكُمۡ ءَامَنُواْ بِٱلَّذِيٓ أُرۡسِلۡتُ بِهِۦ وَطَآئِفَةٞ لَّمۡ يُؤۡمِنُواْ فَٱصۡبِرُواْ حَتَّىٰ يَحۡكُمَ ٱللَّهُ بَيۡنَنَاۚ وَهُوَ خَيۡرُ ٱلۡحَٰكِمِينَ ٨٧","وإن كان طائفة منكم آمنوا بالذي أرسلت به وطائفة لم يؤمنوا فاصبروا حتى يحكم الله بيننا وهو خير الحاكمين","އަދި ތިޔަބައިމީހުންކުރެ އެއްބަޔަކު، ތިމަންކަލޭގެފާނު އެކަމަކާއިގެން ފޮނުއްވެވިކަމަކަށް އީމާން ވެފައި، އަނެއްބަޔަކު އީމާން ނުވިނަމަ، ތިމަންމެންގެ މެދުގައި ﷲ ހުކުމްކުރައްވައިފުމަށް ދާނދެން، ތިޔަބައިމީހުން ކެތްކުރާށެވެ! އެކަލާނގެއީ، ހުކުމްކުރައްވާ އެންމެ ހެޔޮ ރަސްކަލާނގެއެވެ.","",""],["₇ سورة الأعراف","88","۞قَالَ ٱلۡمَلَأُ ٱلَّذِينَ ٱسۡتَكۡبَرُواْ مِن قَوۡمِهِۦ لَنُخۡرِجَنَّكَ يَٰشُعَيۡبُ وَٱلَّذِينَ ءَامَنُواْ مَعَكَ مِن قَرۡيَتِنَآ أَوۡ لَتَعُودُنَّ فِي مِلَّتِنَاۚ قَالَ أَوَلَوۡ كُنَّا كَٰرِهِينَ ٨٨","قال الملأ الذين استكبروا من قومه لنخرجنك يا شعيب والذين آمنوا معك من قريتنا أو لتعودن في ملتنا قال أولو كنا كارهين","އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ތެރެއިން ކިބުރުވެރިވެގަތް ބޮޑުން ބުނޫއެވެ. އޭ ޝުއައިބުގެފާނެވެ! ކަލޭގެފާނާއި، ކަލޭގެފާނުގެ އަރިހުގައި އީމާން ވެގެންތިބިމީހުން، ތިމަންމެންގެ ރަށުން ބޭރުކޮށްލައިފާހުށީމެވެ. ނުވަތަ ތިމަންމެންގެ ދީނަށް ކަލޭގެފާނު އެނބުރި ވަޑައިގަންނަވާށެވެ! އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިމަންމެން (އެކަމަށް) ނުރުހޭ ޙާލުގައި ވީނަމަވެސް ހެއްޔެވެ؟","",""],["₇ سورة الأعراف","89","قَدِ ٱفۡتَرَيۡنَا عَلَى ٱللَّهِ كَذِبًا إِنۡ عُدۡنَا فِي مِلَّتِكُم بَعۡدَ إِذۡ نَجَّىٰنَا ٱللَّهُ مِنۡهَاۚ وَمَا يَكُونُ لَنَآ أَن نَّعُودَ فِيهَآ إِلَّآ أَن يَشَآءَ ٱللَّهُ رَبُّنَاۚ وَسِعَ رَبُّنَا كُلَّ شَيۡءٍ عِلۡمًاۚ عَلَى ٱللَّهِ تَوَكَّلۡنَاۚ رَبَّنَا ٱفۡتَحۡ بَيۡنَنَا وَبَيۡنَ قَوۡمِنَا بِٱلۡحَقِّ وَأَنتَ خَيۡرُ ٱلۡفَٰتِحِينَ ٨٩","قد افترينا على الله كذبا إن عدنا في ملتكم بعد إذ نجانا الله منها وما يكون لنا أن نعود فيها إلا أن يشاء الله ربنا وسع ربنا كل شيء علما على الله توكلنا ربنا افتح بيننا وبين قومنا بالحق وأنت خير الفاتحين","ތިޔަބައިމީހުންގެ ދީނަށް، ތިމަންމެން އެނބުރި ހިނގައްޖެނަމަ، ހަމަކަށަވަރުން، ތިމަންމެންވާހުށީ، ﷲ، ތިމަންމެން އެ ދީނުން މިންޖުކުރެއްވުމަށް ފަހުގައި، ﷲއާމެދު، ދޮގެއްހެދި ބަޔަކު ކަމުގައެވެ. އަދި ތިމަންމެންގެ ވެރި ﷲ އިރާދަކުރައްވައިފިއްޔާ މެނުވީ، ތިމަންމެންނަކަށް އެ ދީނަށް އެނބުރިއެއް ނުދެވޭނެތެވެ. ތިމަންމެންގެ ވެރިރަސްކަލާނގެ ދެނެވޮޑިގަތުން، ހުރިހާ އެއްޗަކަށް ތަނަވަސްވެގެންވެއެވެ. ތިމަންމެން ވަކީލުކުރަނީ، ﷲއަށެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެންނާއި، އަޅަމެންގެ ގައުމުގެމީހުންނާ ދެމެދު، ހައްގު ގޮތުގައި ހުކުމްކުރައްވާނދޭވެ! އިބަރަސްކަލާނގެއީ، ހުކުމްކުރައްވާ އެންމެހެޔޮ ރަސްކަލާނގެއެވެ.","",""],["₇ سورة الأعراف","90","وَقَالَ ٱلۡمَلَأُ ٱلَّذِينَ كَفَرُواْ مِن قَوۡمِهِۦ لَئِنِ ٱتَّبَعۡتُمۡ شُعَيۡبًا إِنَّكُمۡ إِذٗا لَّخَٰسِرُونَ ٩٠","وقال الملأ الذين كفروا من قومه لئن اتبعتم شعيبا إنكم إذا لخاسرون","އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ތެރެއިން، ކާފިރު ވެގަތް ބޮޑުން ބުނޫއެވެ. ޝުއައިބުގެފާނަށް ތިޔަބައިމީހުން ތަބާ ވެއްޖެނަމަ، ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ވާހުށީ، ގެއްލެނިވެގެންވާ ބަޔަކު ކަމުގައެވެ.","",""],["₇ سورة الأعراف","91","فَأَخَذَتۡهُمُ ٱلرَّجۡفَةُ فَأَصۡبَحُواْ فِي دَارِهِمۡ جَٰثِمِينَ ٩١","فأخذتهم الرجفة فأصبحوا في دارهم جاثمين","ދެންފަހެ، ބިރުވެރި ބިންހެލުމެއް، އެއުރެންނަށް އައިސްޖެހުނެވެ. އަދި އެއުރެންގެ ގެތަކުގައި ކަކޫމައްޗަށް ތިރިވެ، މަރުވެފައިތިބި ބަޔަކު ކަމުގައި އެއުރެން ވެއްޖައޫއެވެ.","",""],["₇ سورة الأعراف","92","ٱلَّذِينَ كَذَّبُواْ شُعَيۡبٗا كَأَن لَّمۡ يَغۡنَوۡاْ فِيهَاۚ ٱلَّذِينَ كَذَّبُواْ شُعَيۡبٗا كَانُواْ هُمُ ٱلۡخَٰسِرِينَ ٩٢","الذين كذبوا شعيبا كأن لم يغنوا فيها الذين كذبوا شعيبا كانوا هم الخاسرين","ޝުއައިބުގެފާނު ދޮގުކުޅަ މީހުން، އެގެތަކުގައި ދިރިނޫޅޭފަދައެވެ. ޝުއައިބުގެފާނު ދޮގުކުޅަ މީހުންވީ، ހަމަ، ގެއްލެނިވެގެންވާ ބަޔަކު ކަމުގައެވެ.","",""],["₇ سورة الأعراف","93","فَتَوَلَّىٰ عَنۡهُمۡ وَقَالَ يَٰقَوۡمِ لَقَدۡ أَبۡلَغۡتُكُمۡ رِسَٰلَٰتِ رَبِّي وَنَصَحۡتُ لَكُمۡۖ فَكَيۡفَ ءَاسَىٰ عَلَىٰ قَوۡمٖ كَٰفِرِينَ ٩٣","فتولى عنهم وقال يا قوم لقد أبلغتكم رسالات ربي ونصحت لكم فكيف آسى على قوم كافرين","ދެން އެކަލޭގެފާނު، އެއުރެންގެ ކިބައިން ދުރުހެލިވެ ވަޑައިގަތެވެ. އަދި އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ހަމަކަށަވަރުން، އަހުރެންގެ ވެރިރަސްކަލާނގެ ރަސޫލު ކަން ތިޔަބައިމީހުންނަށް އިއްވީމެވެ. އަދި ތިޔަބައިމީހުންނަށް އަހުރެން ނަސޭހަތް ތެރިވީމެވެ. ފަހެ، ކާފިރުވި ބަޔަކުގެ މައްޗަށް އަހުރެން ހިތާމަކުރާނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["₇ سورة الأعراف","94","وَمَآ أَرۡسَلۡنَا فِي قَرۡيَةٖ مِّن نَّبِيٍّ إِلَّآ أَخَذۡنَآ أَهۡلَهَا بِٱلۡبَأۡسَآءِ وَٱلضَّرَّآءِ لَعَلَّهُمۡ يَضَّرَّعُونَ ٩٤","وما أرسلنا في قرية من نبي إلا أخذنا أهلها بالبأساء والضراء لعلهم يضرعون","އެރަށެއްގެ އަހުލުވެރިންނަށް ދަތިކަމާއި، ބަލިމަޑުކަން ނުޖައްސަވާ އެއްވެސް ރަށަކަށް ތިމަންރަސްކަލާނގެ ނަބިއްޔަކު ނުފޮނުއްވަމެވެ. އެއީ އެމީހުން މަޑުމޮޅިވުމަށެވެ.","",""],["₇ سورة الأعراف","95","ثُمَّ بَدَّلۡنَا مَكَانَ ٱلسَّيِّئَةِ ٱلۡحَسَنَةَ حَتَّىٰ عَفَواْ وَّقَالُواْ قَدۡ مَسَّ ءَابَآءَنَا ٱلضَّرَّآءُ وَٱلسَّرَّآءُ فَأَخَذۡنَٰهُم بَغۡتَةٗ وَهُمۡ لَا يَشۡعُرُونَ ٩٥","ثم بدلنا مكان السيئة الحسنة حتى عفوا وقالوا قد مس آباءنا الضراء والسراء فأخذناهم بغتة وهم لا يشعرون","ދެން، ނުބައި ޙާލަތް، ރަނގަޅު ޙާލަތަށް ތިމަންރަސްކަލާނގެ ބަދަލުކުރެއްވީމެވެ. (އެއީ) އެއުރެން ގިނަވެ، ތަނަވަސްވެއްޖައުމަށް ދާނދެނެވެ. ދެން އެއުރެން ބުނޫއެވެ. ހަމަކަށަވަރުން، ތިމަންމެންގެ ކާބަފައިންނަށް ތަދުމަޑުކަމާއި، ތިޔާގިކަން ލިބުނެވެ. ދެން، އެއުރެންނަށް ނޭނގިތިއްބައި، ކުއްލިއަކަށް، ތިމަންރަސްކަލާނގެ (ކޯފާގެ އަޒާބުން) އެއުރެން ހިއްޕެވީމެވެ.","",""],["₇ سورة الأعراف","96","وَلَوۡ أَنَّ أَهۡلَ ٱلۡقُرَىٰٓ ءَامَنُواْ وَٱتَّقَوۡاْ لَفَتَحۡنَا عَلَيۡهِم بَرَكَٰتٖ مِّنَ ٱلسَّمَآءِ وَٱلۡأَرۡضِ وَلَٰكِن كَذَّبُواْ فَأَخَذۡنَٰهُم بِمَا كَانُواْ يَكۡسِبُونَ ٩٦","ولو أن أهل القرى آمنوا واتقوا لفتحنا عليهم بركات من السماء والأرض ولكن كذبوا فأخذناهم بما كانوا يكسبون","ރަށްތަކުގެ އަހުލުވެރިން، އީމާންވެ ތަގުވާވެރިވީނަމަ، ހަމަކަށަވަރުން، އުޑުންނާއި، ބިމުން، ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް ބަރަކާތްގެ މަގުތައް ހުޅުއްވައިދެއްވީމުހެވެ. އެހެނެއްކަމަކު، އެއުރެން ދޮގުކުރޫއެވެ. ދެން، އެއުރެން ހޯދައި އުޅުނު ޢަމަލު ތަކަށްޓަކައި، ތިމަންރަސްކަލާނގެ (ކޯފާގެ އަޒާބުން) އެއުރެން ހިއްޕެވީމެވެ.","",""],["₇ سورة الأعراف","97","أَفَأَمِنَ أَهۡلُ ٱلۡقُرَىٰٓ أَن يَأۡتِيَهُم بَأۡسُنَا بَيَٰتٗا وَهُمۡ نَآئِمُونَ ٩٧","أفأمن أهل القرى أن يأتيهم بأسنا بياتا وهم نائمون","ފަހެ، ރަށްތަކުގެ އަހުލުވެރިން އެއުރެން ރޭގަނޑުގައި ނިދާފައިތިއްބައި އެއުރެންގެ ގާތަށް ތިމަންރަސްކަލާނގެ ކޯފާގެ އަޒާބު އަތުވެދާނެކަމާމެދު (ބިރެއްނެތި) އަމާންވެ ތިބީހެއްޔެވެ؟","",""],["₇ سورة الأعراف","98","أَوَ أَمِنَ أَهۡلُ ٱلۡقُرَىٰٓ أَن يَأۡتِيَهُم بَأۡسُنَا ضُحٗى وَهُمۡ يَلۡعَبُونَ ٩٨","أوأمن أهل القرى أن يأتيهم بأسنا ضحى وهم يلعبون","ނުވަތަ ރަށްތަކުގެ އަހުލުވެރިން، އެއުރެން ކުޅެކުޅެތިއްބައި ދުވާލުގެ ޟުޙާ ވަގުތުގައި އެއުރެންގެ ގާތަށް ތިމަންރަސްކަލާނގެ ކޯފާގެ އަޒާބު އަތުވެދާނެ ކަމާމެދަކު (ބިރެއްނެތި) އަމާންވެ ތިބީހެއްޔެވެ؟","",""],["₇ سورة الأعراف","99","أَفَأَمِنُواْ مَكۡرَ ٱللَّهِۚ فَلَا يَأۡمَنُ مَكۡرَ ٱللَّهِ إِلَّا ٱلۡقَوۡمُ ٱلۡخَٰسِرُونَ ٩٩","أفأمنوا مكر الله فلا يأمن مكر الله إلا القوم الخاسرون","ފަހެ، ﷲގެ ރޭއްވެވުމާމެދު އެއުރެން (ބިރެއްނެތި) އަމާންވެ ތިބީހެއްޔެވެ؟ ފަހެ، ގެއްލެނިވެގެންވާ މީހުން މެނުވީ، ﷲގެ ރޭއްވެވުމާމެދު (ބިރެއްނެތި) އަމާންވެގެންނެއް ނުތިބޭނެތެވެ.","",""],["₇ سورة الأعراف","100","أَوَ لَمۡ يَهۡدِ لِلَّذِينَ يَرِثُونَ ٱلۡأَرۡضَ مِنۢ بَعۡدِ أَهۡلِهَآ أَن لَّوۡ نَشَآءُ أَصَبۡنَٰهُم بِذُنُوبِهِمۡۚ وَنَطۡبَعُ عَلَىٰ قُلُوبِهِمۡ فَهُمۡ لَا يَسۡمَعُونَ ١٠٠","أولم يهد للذين يرثون الأرض من بعد أهلها أن لو نشاء أصبناهم بذنوبهم ونطبع على قلوبهم فهم لا يسمعون","ބިމުގެ އަހުލުވެރިންނަށްފަހު، އެ ބިން ވާރުތަވާ މީހުންނަށް ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާނަމަ، އެއުރެންގެ ފާފަތަކުގެ ސަބަބުން ތިމަންރަސްކަލާނގެ އެއުރެންނަށް އަޒާބު ދެއްވައިފާނެކަމާއި، އެއުރެންނީ، އަޑުނީވޭ ބަޔަކު ކަމުގައި ވާނޭގޮތުން، އެއުރެންގެ ހިތްތަކުގައި ސިއްކަގައްސަވައިފާނޭކަން ނޭނގެނީހެއްޔެވެ؟","",""],["₇ سورة الأعراف","101","تِلۡكَ ٱلۡقُرَىٰ نَقُصُّ عَلَيۡكَ مِنۡ أَنۢبَآئِهَاۚ وَلَقَدۡ جَآءَتۡهُمۡ رُسُلُهُم بِٱلۡبَيِّنَٰتِ فَمَا كَانُواْ لِيُؤۡمِنُواْ بِمَا كَذَّبُواْ مِن قَبۡلُۚ كَذَٰلِكَ يَطۡبَعُ ٱللَّهُ عَلَىٰ قُلُوبِ ٱلۡكَٰفِرِينَ ١٠١","تلك القرى نقص عليك من أنبائها ولقد جاءتهم رسلهم بالبينات فما كانوا ليؤمنوا بما كذبوا من قبل كذلك يطبع الله على قلوب الكافرين","އެއީ ރަށްތަކެވެ. އެ ރަށްތަކުގެ ޚަބަރުތައް، ކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ ކިޔައިދެއްވަމެވެ. ހަމަކަށަވަރުން، އެއުރެންގެ ގާތަށް، ބަޔާންވެގެންވާ ހެކިތަކާއިގެން އެއުރެންގެ ރަސޫލުން ވަޑައިގަތެވެ. ފަހެ، އެއުރެން ކުރިން ދޮގުކުޅަ އެއްޗަކަށް އީމާން ވާކަށް އެއުރެންނެތެވެ. ކާފިރުންގެ ހިތްތަކުގައި ﷲ ސިއްކަގައްސަވަނީ އެފަދައިންނެވެ.","",""],["₇ سورة الأعراف","102","وَمَا وَجَدۡنَا لِأَكۡثَرِهِم مِّنۡ عَهۡدٖۖ وَإِن وَجَدۡنَآ أَكۡثَرَهُمۡ لَفَٰسِقِينَ ١٠٢","وما وجدنا لأكثرهم من عهد وإن وجدنا أكثرهم لفاسقين","އަދި އެއުރެންކުރެ ގިނަމީހުން، އެއްވެސް އަހުދެއްގައި (ހިފަހައްޓައިގެން) ވާތީ، ތިމަންރަސްކަލާނގެ ދެކެވޮޑިއެއް ނުގަންނަވަމެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެންކުރެ ގިނަމީހުންނީ، ފާސިގުން ކަމުގައިވާތީ ތިމަންރަސްކަލާނގެ ދެކެވޮޑިގެންވަމެވެ.","",""],["₇ سورة الأعراف","103","ثُمَّ بَعَثۡنَا مِنۢ بَعۡدِهِم مُّوسَىٰ بِـَٔايَٰتِنَآ إِلَىٰ فِرۡعَوۡنَ وَمَلَإِيْهِۦ فَظَلَمُواْ بِهَاۖ فَٱنظُرۡ كَيۡفَ كَانَ عَٰقِبَةُ ٱلۡمُفۡسِدِينَ ١٠٣","ثم بعثنا من بعدهم موسى بآياتنا إلى فرعون وملئه فظلموا بها فانظر كيف كان عاقبة المفسدين","ދެން އެބޭކަލުންނަށްފަހުގައި ފިރްޢައުނާއި އޭނާގެ ބޮޑުންގެ ގާތަށް ތިމަންރަސްކަލާނގެ ހެކިތަކާއިގެން މޫސާގެފާނު ފޮނުއްވީމެވެ. ދެން އެއުރެން އެ ހެކިތަކާ ދެކޮޅުހެދޫއެވެ. ފަހެ، ފަސާދަކުރާ މީހުންގެ ނިމުންހުރީ، ކިހިނަކުންކަން ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާށެވެ!","",""],["₇ سورة الأعراف","104","وَقَالَ مُوسَىٰ يَٰفِرۡعَوۡنُ إِنِّي رَسُولٞ مِّن رَّبِّ ٱلۡعَٰلَمِينَ ١٠٤","وقال موسى يا فرعون إني رسول من رب العالمين","މޫސާގެފާނު ވިދާޅުވިއެވެ. އޭ ފިރްޢައުނެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނީ، އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ފޮނުއްވި ރަސޫލަކީމެވެ.","",""],["₇ سورة الأعراف","105","حَقِيقٌ عَلَىٰٓ أَن لَّآ أَقُولَ عَلَى ٱللَّهِ إِلَّا ٱلۡحَقَّۚ قَدۡ جِئۡتُكُم بِبَيِّنَةٖ مِّن رَّبِّكُمۡ فَأَرۡسِلۡ مَعِيَ بَنِيٓ إِسۡرَـٰٓءِيلَ ١٠٥","حقيق على أن لا أقول على الله إلا الحق قد جئتكم ببينة من ربكم فأرسل معي بني إسرائيل","ތިމަންކަލޭގެފާނަށް ހައްގު ވެގެންވަނީ، ހައްގު ތެދުފިޔަވައި (އެހެން އެއްވެސް އެއްޗެއް) ﷲއާމެދު ތިމަންކަލޭގެފާނު ވިދާޅުނުވުމެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ގާތަށް ތިމަންކަލޭގެފާނު މިވަޑައިގަތީ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ބަޔާންވެގެންވާ ހެތްކަކާއިގެންނެވެ. ފަހެ، އިސްރާއީލުގެދަރިން ތިމަންކަލޭގެފާނާ އެކުގައި ފޮނުވާށެވެ!","",""],["₇ سورة الأعراف","106","قَالَ إِن كُنتَ جِئۡتَ بِـَٔايَةٖ فَأۡتِ بِهَآ إِن كُنتَ مِنَ ٱلصَّـٰدِقِينَ ١٠٦","قال إن كنت جئت بآية فأت بها إن كنت من الصادقين","އޭނާ ދެންނެވިއެވެ. ކަލޭގެފާނު ތިޔަވަޑައިގަތީ، ހެތްކަކާއިގެން ކަމުގައިވާނަމަ (އަދި) ތެދުވެރިންގެ ތެރެއިން ކަލޭގެފާނު ވާނަމަ، ފަހެ، އެ ހެތްކެއް ނިކަން ގެންނަވައި ބައްލަވާށެވެ!","",""],["₇ سورة الأعراف","107","فَأَلۡقَىٰ عَصَاهُ فَإِذَا هِيَ ثُعۡبَانٞ مُّبِينٞ ١٠٧","فألقى عصاه فإذا هي ثعبان مبين","ދެން އެކަލޭގެފާނުގެ އަސާކޮޅު އެކަލޭގެފާނު އެއްލެވިއެވެ. ފަހެ، އެހިނދު، އެ އަސާކޮޅު ފާޅުވެގެންވާ ހަރުފަޔަކަށް ވެއްޖެއެވެ.","",""],["₇ سورة الأعراف","108","وَنَزَعَ يَدَهُۥ فَإِذَا هِيَ بَيۡضَآءُ لِلنَّـٰظِرِينَ ١٠٨","ونزع يده فإذا هي بيضاء للناظرين","އަދި އެކަލޭގެފާނުގެ އަތްޕުޅު ނެރުއްވިއެވެ. ފަހެ، އެހިނދު، ބަލަންތިބި މީހުންނަށް އެ އަތްޕުޅު ފެންނަންއޮތީ، ވިދަވިދައިއޮތް ހުދު އަތްޕުޅެއްކަމުގައެވެ.","",""],["₇ سورة الأعراف","109","قَالَ ٱلۡمَلَأُ مِن قَوۡمِ فِرۡعَوۡنَ إِنَّ هَٰذَا لَسَٰحِرٌ عَلِيمٞ ١٠٩","قال الملأ من قوم فرعون إن هذا لساحر عليم","ފިރްޢައުނުގެ ގައުމުގެބޮޑުން ބުނޫއެވެ. ހަމަކަށަވަރުން، މިއީ މޮޅަށްދަންނަ ޖާދޫގަރެއްކަން ކަށަވަރެވެ.","",""],["₇ سورة الأعراف","110","يُرِيدُ أَن يُخۡرِجَكُم مِّنۡ أَرۡضِكُمۡۖ فَمَاذَا تَأۡمُرُونَ ١١٠","يريد أن يخرجكم من أرضكم فماذا تأمرون","އެކަލޭގެފާނު އެދިވަޑައިގަންނަވަނީ، ތިޔަބައިމީހުންގެ ބިމުން ތިޔަބައިމީހުން ނެރެލެއްވުމަށެވެ. ވީމާ، ތިޔަބައިމީހުން އަމުރުކުރާ ގޮތަކީ ކޮބައިހެއްޔެވެ؟","",""],["₇ سورة الأعراف","111","قَالُوٓاْ أَرۡجِهۡ وَأَخَاهُ وَأَرۡسِلۡ فِي ٱلۡمَدَآئِنِ حَٰشِرِينَ ١١١","قالوا أرجه وأخاه وأرسل في المدائن حاشرين","އެއުރެން ބުނޫއެވެ. އެކަލޭގެފާނާއި، އެކަލޭގެފާނުގެ އަޚު، އިހަށް ބައިތިއްބާށެވެ! އަދި (މީހުން) އެއްކުރުމަށް ގޮވާބަޔަކު، ރަށުތެރެއަށް ފޮނުވާށެވެ!","",""],["₇ سورة الأعراف","112","يَأۡتُوكَ بِكُلِّ سَٰحِرٍ عَلِيمٖ ١١٢","يأتوك بكل ساحر عليم","އޭރުން، އެއުރެން (ގޮސް) މޮޅަށް ދަންނަ ހުރިހާ ޖާދޫގަރުން ކަލޭގެގާތަށް ގެނެސް ދޭނެއެވެ.","",""],["₇ سورة الأعراف","113","وَجَآءَ ٱلسَّحَرَةُ فِرۡعَوۡنَ قَالُوٓاْ إِنَّ لَنَا لَأَجۡرًا إِن كُنَّا نَحۡنُ ٱلۡغَٰلِبِينَ ١١٣","وجاء السحرة فرعون قالوا إن لنا لأجرا إن كنا نحن الغالبين","ފިރްޢައުނުގެ ގާތަށް ޖާދޫގަރުން އަތުވެއްޖެއެވެ. އެއުރެން ބުނޫއެވެ. ތިމަންމެން މޮޅުވެއްޖެނަމަ، ހަމަކަށަވަރުން، ތިމަންމެންނަށް އުޖޫރައެއް އޮންނަންވާނެއެވެ.","",""],["₇ سورة الأعراف","114","قَالَ نَعَمۡ وَإِنَّكُمۡ لَمِنَ ٱلۡمُقَرَّبِينَ ١١٤","قال نعم وإنكم لمن المقربين","އޭނާ ބުންޏެވެ. އާނއެކެވެ! އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުންވާހުށީ، ގާތްކުރެވިގެންވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["₇ سورة الأعراف","115","قَالُواْ يَٰمُوسَىٰٓ إِمَّآ أَن تُلۡقِيَ وَإِمَّآ أَن نَّكُونَ نَحۡنُ ٱلۡمُلۡقِينَ ١١٥","قالوا يا موسى إما أن تلقي وإما أن نكون نحن الملقين","އެއުރެން ދެންނެވޫއެވެ. އޭ މޫސާގެފާނެވެ! ކަލޭގެފާނު (ކުރިން) އެއްލަވާނީއެވެ. ނޫންނަމަ (ކުރިން) އެއްލާ މީހުންކަމުގައި ތިމަންމެން ވެދާނޫއެވެ.","",""],["₇ سورة الأعراف","116","قَالَ أَلۡقُواْۖ فَلَمَّآ أَلۡقَوۡاْ سَحَرُوٓاْ أَعۡيُنَ ٱلنَّاسِ وَٱسۡتَرۡهَبُوهُمۡ وَجَآءُو بِسِحۡرٍ عَظِيمٖ ١١٦","قال ألقوا فلما ألقوا سحروا أعين الناس واسترهبوهم وجاءوا بسحر عظيم","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން އެއްލާށެވެ! ދެންފަހެ، އެއުރެން އެއްލިހިނދު، މީސްތަކުންގެ ލޯތަކަށް ޖާދޫދައްކައި، އެއުރެން ބިރުގެންނެވޫއެވެ. އަދި ބޮޑުވެގެންވާ ޖާދޫއެއް އެމީހުން ގެނައޫއެވެ.","",""],["₇ سورة الأعراف","117","۞وَأَوۡحَيۡنَآ إِلَىٰ مُوسَىٰٓ أَنۡ أَلۡقِ عَصَاكَۖ فَإِذَا هِيَ تَلۡقَفُ مَا يَأۡفِكُونَ ١١٧","وأوحينا إلى موسى أن ألق عصاك فإذا هي تلقف ما يأفكون","ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް ވަހީކުރެއްވީމެވެ. ކަލޭގެފާނުގެ އަސާކޮޅު އެއްލަވާށެވެ! ދެން (އެކަލޭގެފާނުގެ އަސާކޮޅު އެއްލެވީމާ) އެހާރުން އެ އަސާކޮޅު އެއުރެން ދޮގުން ހަދައިގެން ދެއްކި ތަކެތި ކައި ދިރުވައިފިއެވެ.","",""],["₇ سورة الأعراف","118","فَوَقَعَ ٱلۡحَقُّ وَبَطَلَ مَا كَانُواْ يَعۡمَلُونَ ١١٨","فوقع الحق وبطل ما كانوا يعملون","ފަހެ، ހައްގު ތެދު ފާޅުވެއްޖެއެވެ. އަދި އެއުރެން ކޮށްއުޅުނު ކަންތައް ބާތިލު ވެގެން ހިނގައްޖެއެވެ.","",""],["₇ سورة الأعراف","119","فَغُلِبُواْ هُنَالِكَ وَٱنقَلَبُواْ صَٰغِرِينَ ١١٩","فغلبوا هنالك وانقلبوا صاغرين","ފަހެ، އެތާނގައި އެއުރެން ދެރަވެ ބަލިވެއްޖައޫއެވެ. އަދި އެއުރެން ނިކަމެތީންކަމުގައި ވެގެން ހިނގައްޖައޫއެވެ.","",""],["₇ سورة الأعراف","120","وَأُلۡقِيَ ٱلسَّحَرَةُ سَٰجِدِينَ ١٢٠","وألقي السحرة ساجدين","އަދި އެ ޖާދޫގަރުން ސަޖިދަށް ތިރިވެއްޖައޫއެވެ.","",""],["₇ سورة الأعراف","121","قَالُوٓاْ ءَامَنَّا بِرَبِّ ٱلۡعَٰلَمِينَ ١٢١","قالوا آمنا برب العالمين","އެއުރެން ބުނެފޫއެވެ. އާލަމްތަކުގެ ވެރިރަސްކަލާނގެއަށް ތިމަންމެން އީމާން ވެއްޖައީމުއެވެ.","",""],["₇ سورة الأعراف","122","رَبِّ مُوسَىٰ وَهَٰرُونَ ١٢٢","رب موسى وهارون","(އެއީ) މޫސާގެފާނާއި، ހާރޫނުގެފާނުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["₇ سورة الأعراف","123","قَالَ فِرۡعَوۡنُ ءَامَنتُم بِهِۦ قَبۡلَ أَنۡ ءَاذَنَ لَكُمۡۖ إِنَّ هَٰذَا لَمَكۡرٞ مَّكَرۡتُمُوهُ فِي ٱلۡمَدِينَةِ لِتُخۡرِجُواْ مِنۡهَآ أَهۡلَهَاۖ فَسَوۡفَ تَعۡلَمُونَ ١٢٣","قال فرعون آمنتم به قبل أن آذن لكم إن هذا لمكر مكرتموه في المدينة لتخرجوا منها أهلها فسوف تعلمون","ފިރްޢައުނު ބުންޏެވެ. ތިޔަބައިމީހުންނަށް ތިމަން އިޒުނަ ނުދެނީސް، ތިޔަބައިމީހުން އެކަލޭގެފާނަށް އީމާން ވީހެއްޔެވެ؟ ހަމަކަށަވަރުން، މިއީ ރަށުގެ އަހުލުވެރިން ރަށުން ނެރެލުމަށްޓަކައި ތިޔަބައިމީހުން ރަށުތެރޭގައި ރޭވި ރޭވުމެއްކަން ކަށަވަރެވެ. ނިކަންހުރެ ތިޔަބައިމީހުންނަށް އެނގޭނެއެވެ.","",""],["₇ سورة الأعراف","124","لَأُقَطِّعَنَّ أَيۡدِيَكُمۡ وَأَرۡجُلَكُم مِّنۡ خِلَٰفٖ ثُمَّ لَأُصَلِّبَنَّكُمۡ أَجۡمَعِينَ ١٢٤","لأقطعن أيديكم وأرجلكم من خلاف ثم لأصلبنكم أجمعين","ތިޔަބައިމީހުންގެ އަތްތަކާއި، ފައިތައް ތަފާތުވާގޮތަށް (އެބަހީ: ކަނާތާއި ވާތުފައި ނުވަތަ ވާތާއި ކަނާތުފައި) ތިމަން ބުރިކުރާހުށީމެވެ. ދެން ހަމަކަށަވަރުން، ތިޔަހުރިހާ އެންމެން ޞަލީބަށް އަރުވާހުށީމެވެ.","",""],["₇ سورة الأعراف","125","قَالُوٓاْ إِنَّآ إِلَىٰ رَبِّنَا مُنقَلِبُونَ ١٢٥","قالوا إنا إلى ربنا منقلبون","އެއުރެން ބުނޫއެވެ. ހަމަކަށަވަރުން، ތިމަންމެން އެނބުރިދާހުށީ ތިމަންމެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["₇ سورة الأعراف","126","وَمَا تَنقِمُ مِنَّآ إِلَّآ أَنۡ ءَامَنَّا بِـَٔايَٰتِ رَبِّنَا لَمَّا جَآءَتۡنَاۚ رَبَّنَآ أَفۡرِغۡ عَلَيۡنَا صَبۡرٗا وَتَوَفَّنَا مُسۡلِمِينَ ١٢٦","وما تنقم منا إلا أن آمنا بآيات ربنا لما جاءتنا ربنا أفرغ علينا صبرا وتوفنا مسلمين","ތިމަންމެންގެ ކިބައިން ތިޔަބަދަލުހިފަނީ، ތިމަންމެންގެ ވެރިރަސްކަލާނގެ އާޔަތްތައް ތިމަންމެންނަށް އައުމުން، އެއަށް ތިމަންމެން އީމާން ވުން ފިޔަވައި އެހެން ކަމަކަށްޓަކައެއްނޫނެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެންގެ މައްޗަށް ކެތްތެރިކަން އޮއްސަވާނދޭވެ! އަދި މުސްލިމުން ކަމުގައި އަޅަމެން މަރުގަންނަވާނދޭވެ!","",""],["₇ سورة الأعراف","127","وَقَالَ ٱلۡمَلَأُ مِن قَوۡمِ فِرۡعَوۡنَ أَتَذَرُ مُوسَىٰ وَقَوۡمَهُۥ لِيُفۡسِدُواْ فِي ٱلۡأَرۡضِ وَيَذَرَكَ وَءَالِهَتَكَۚ قَالَ سَنُقَتِّلُ أَبۡنَآءَهُمۡ وَنَسۡتَحۡيِۦ نِسَآءَهُمۡ وَإِنَّا فَوۡقَهُمۡ قَٰهِرُونَ ١٢٧","وقال الملأ من قوم فرعون أتذر موسى وقومه ليفسدوا في الأرض ويذرك وآلهتك قال سنقتل أبناءهم ونستحيي نساءهم وإنا فوقهم قاهرون","ފިރްޢައުނުގެ ގައުމުގެބޮޑުން ބުނޫއެވެ. މޫސާގެފާނާއި، އެކަލޭގެފާނުގެ ގައުމުގެމީހުން، ކަލެޔާއި ކަލޭގެ އިލާހު ންތައް ދޫކޮށް، ބިމުގައި ފަސާދަ އުފެއްދުމަށް ތިޔަ ދޫކޮށްލަނީހެއްޔެވެ؟ އޭނާ ބުންޏެވެ. ތިމަންމެން އެއުރެންގެ ފިރިހެންދަރިން މަރާހުށީމެވެ. އަދި އެއުރެންގެ ތެރެއިން އަންހެނުން ނުމަރައި ބައިތިއްބާނޫއެވެ. ހަމަކަށަވަރުން، ތިމަންމެންނީ އެއުރެންގެ މައްޗަށް ގަދަކަން ލިބިގެންވާ ބަޔަކީމުއެވެ.","",""],["₇ سورة الأعراف","128","قَالَ مُوسَىٰ لِقَوۡمِهِ ٱسۡتَعِينُواْ بِٱللَّهِ وَٱصۡبِرُوٓاْۖ إِنَّ ٱلۡأَرۡضَ لِلَّهِ يُورِثُهَا مَن يَشَآءُ مِنۡ عِبَادِهِۦۖ وَٱلۡعَٰقِبَةُ لِلۡمُتَّقِينَ ١٢٨","قال موسى لقومه استعينوا بالله واصبروا إن الأرض لله يورثها من يشاء من عباده والعاقبة للمتقين","މޫސާގެފާނު، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން، ﷲގެ ހަޒުރަތުން ވާގިއެދޭށެވެ! އަދި ތިޔަބައިމީހުން ކެތްކުރާށެވެ! ހަމަކަށަވަރުން، ބިން މަލަކަ ވެގެންވަނީ ﷲއަށެވެ. އެކަލާނގެ އަޅުންގެ ތެރެއިން އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް، އެ ބިން ވާރުތަކޮށްދެއްވައެވެ. އަދި ހެޔޮ ނިމުންވަނީ، ތަގުވާވެރިންނަށެވެ.","",""],["₇ سورة الأعراف","129","قَالُوٓاْ أُوذِينَا مِن قَبۡلِ أَن تَأۡتِيَنَا وَمِنۢ بَعۡدِ مَا جِئۡتَنَاۚ قَالَ عَسَىٰ رَبُّكُمۡ أَن يُهۡلِكَ عَدُوَّكُمۡ وَيَسۡتَخۡلِفَكُمۡ فِي ٱلۡأَرۡضِ فَيَنظُرَ كَيۡفَ تَعۡمَلُونَ ١٢٩","قالوا أوذينا من قبل أن تأتينا ومن بعد ما جئتنا قال عسى ربكم أن يهلك عدوكم ويستخلفكم في الأرض فينظر كيف تعملون","އެއުރެން ދެންނެވޫއެވެ. ތިމަންމެންގެ ގާތަށް ކަލޭގެފާނު ވަޑައިގަތުމުގެ ކުރިންނާއި، ތިމަންމެންގެ ގާތަށް ކަލޭގެފާނު ވަޑައިގަތުމުގެ ފަހުންވެސް، ތިމަންމެންނަށް އުނދަގޫ ލިބެމުންދިޔައެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ތިޔަބައިމީހުންގެ އަދާވަތް ތެރިޔާ ހަލާކު ކުރައްވައި، ތިޔަބައިމީހުން ބިމުގައި ވެރިކުރައްވައިފާ ހުށްޓެވެ. ދެން ތިޔަބައިމީހުން ޢަމަލުކުރަނީ ކިހިނަކުންކަން، އެކަލާނގެ ބައްލަވާވޮޑިގެންވާނެތެވެ.","",""],["₇ سورة الأعراف","130","وَلَقَدۡ أَخَذۡنَآ ءَالَ فِرۡعَوۡنَ بِٱلسِّنِينَ وَنَقۡصٖ مِّنَ ٱلثَّمَرَٰتِ لَعَلَّهُمۡ يَذَّكَّرُونَ ١٣٠","ولقد أخذنا آل فرعون بالسنين ونقص من الثمرات لعلهم يذكرون","ހަމަކަށަވަރުން، ތަދުމަޑު އަހަރުތަކާއި، މޭވާތަކުގެ އުނިކަން މެދުވެރިކުރައްވައި، ތިމަންރަސްކަލާނގެ ފިރްޢައުނުގެ މީހުން ހިއްޕެވީމެވެ. (އެއީ) އެއުރެން ހަނދުމަކުރުމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","131","فَإِذَا جَآءَتۡهُمُ ٱلۡحَسَنَةُ قَالُواْ لَنَا هَٰذِهِۦۖ وَإِن تُصِبۡهُمۡ سَيِّئَةٞ يَطَّيَّرُواْ بِمُوسَىٰ وَمَن مَّعَهُۥٓۗ أَلَآ إِنَّمَا طَـٰٓئِرُهُمۡ عِندَ ٱللَّهِ وَلَٰكِنَّ أَكۡثَرَهُمۡ لَا يَعۡلَمُونَ ١٣١","فإذا جاءتهم الحسنة قالوا لنا هذه وإن تصبهم سيئة يطيروا بموسى ومن معه ألا إنما طائرهم عند الله ولكن أكثرهم لا يعلمون","ފަހެ، އެއުރެންނާ ހަމަޔަށް ހެޔޮގޮތް އަތުވެއްޖެނަމަ، މިއީ ތިމަންމެންނަށް އޮތްކަމެކޭ އެއުރެން ބުނެތެވެ. އަދި އެއުރެންނަށް ނުބައިކަމެއް ޖެހިއްޖެނަމަ، މޫސާގެފާނާއި، އެކަލޭގެފާނުގެ އަރިހުގައިވާ މީހުންގެ ސުންޕާކަމުން ޖެހުނުކަމެއްކަމުގައި އެއުރެން ހަދަތެވެ. ދަންނާށެވެ! އެއުރެންނަށް ސުންޕާގޮތް މެދުވެރިވުންވަނީ، ﷲގެ ހަޒުރަތު ގައެވެ. އެހެނެއްކަމަކު، އެއުރެންކުރެ ގިނަމީހުންނަކަށް ނޭނގެއެވެ.","",""],["₇ سورة الأعراف","132","وَقَالُواْ مَهۡمَا تَأۡتِنَا بِهِۦ مِنۡ ءَايَةٖ لِّتَسۡحَرَنَا بِهَا فَمَا نَحۡنُ لَكَ بِمُؤۡمِنِينَ ١٣٢","وقالوا مهما تأتنا به من آية لتسحرنا بها فما نحن لك بمؤمنين","އެއުރެން ދެންނެވޫއެވެ. ތިމަންމެން، އޭގެ ޖާދޫގައި ޖެއްސެވުމަށްޓަކައި އާޔަތްތަކުގެ ތެރެއިން ކޮންމެފަދަ އާޔަތެއް ކަލޭގެފާނު ތިމަންމެންނަށް ގެނެސްދެއްވި ކަމުގައިވިޔަސް، ކަލޭގެފާނަށް އީމާންވާ ބަޔަކު ކަމުގައި ތިމަންމެން ނުވާހުށީމުއެވެ.","",""],["₇ سورة الأعراف","133","فَأَرۡسَلۡنَا عَلَيۡهِمُ ٱلطُّوفَانَ وَٱلۡجَرَادَ وَٱلۡقُمَّلَ وَٱلضَّفَادِعَ وَٱلدَّمَ ءَايَٰتٖ مُّفَصَّلَٰتٖ فَٱسۡتَكۡبَرُواْ وَكَانُواْ قَوۡمٗا مُّجۡرِمِينَ ١٣٣","فأرسلنا عليهم الطوفان والجراد والقمل والضفادع والدم آيات مفصلات فاستكبروا وكانوا قوما مجرمين","ދެން ކަނޑައެޅި، ބަޔާންވެގެންހުރި އާޔަތް ތަކެއް ކަމުގައި (ފެންބޮޑުވުމުގެ) ޠޫފާނާއި، ގޮއްފުޅަންގާއި، އުކުނާއި، ބޮކާއި، ލޭ، ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް ފޮނުއްވީމެވެ. ދެންވެސް އެއުރެން ބޮޑާވެގަތޫއެވެ. އަދި އެއުރެން ކުށްވެރި ބަޔަކު ކަމުގައިވިއެވެ.","",""],["₇ سورة الأعراف","134","وَلَمَّا وَقَعَ عَلَيۡهِمُ ٱلرِّجۡزُ قَالُواْ يَٰمُوسَى ٱدۡعُ لَنَا رَبَّكَ بِمَا عَهِدَ عِندَكَۖ لَئِن كَشَفۡتَ عَنَّا ٱلرِّجۡزَ لَنُؤۡمِنَنَّ لَكَ وَلَنُرۡسِلَنَّ مَعَكَ بَنِيٓ إِسۡرَـٰٓءِيلَ ١٣٤","ولما وقع عليهم الرجز قالوا يا موسى ادع لنا ربك بما عهد عندك لئن كشفت عنا الرجز لنؤمنن لك ولنرسلن معك بني إسرائيل","އެއުރެންގެ މައްޗަށް މި އަޒާބު އައިސްޖެހުނުހިނދު އެއުރެން ދެންނެވިއެވެ. އޭ މޫސާގެފާނެވެ! ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ތިމަންމެންނަށްޓަކައި، ދުއާ ކޮށްދެއްވާށެވެ. ކަލޭގެފާނަށް އެކަލާނގެ އަހުދުކުރައްވައި އަންގަވާފައިވާ ގޮތުގެމަތިންނެވެ. ހަމަކަށަވަރުން، ތިމަންމެންގެ ކިބައިން މި އަޒާބު ފިއްލަވައިފިނަމަ، ހަމަކަށަވަރުން، ކަލޭގެފާނަށް ތިމަންމެން އީމާން ވާހުށީމެވެ. އަދި ކަލޭގެފާނުގެ އަރިހުގައި އިސްރާއީލުގެދަރިން ފޮނުވާހުށީމެވެ.","",""],["₇ سورة الأعراف","135","فَلَمَّا كَشَفۡنَا عَنۡهُمُ ٱلرِّجۡزَ إِلَىٰٓ أَجَلٍ هُم بَٰلِغُوهُ إِذَا هُمۡ يَنكُثُونَ ١٣٥","فلما كشفنا عنهم الرجز إلى أجل هم بالغوه إذا هم ينكثون","ފަހެ، ތިމަންރަސްކަލާނގެ އެއުރެންގެ ކިބައިން އެ މުއްދަތެއް ހަމަވަނިވި މުއްދަތަކަށް، އެ އަޒާބު ފިއްލެވިހިނދު، އެހާރުން އަހުދު އުވާލާ ބަޔަކު ކަމުގައި އެއުރެން ވޫއެވެ.","",""],["₇ سورة الأعراف","136","فَٱنتَقَمۡنَا مِنۡهُمۡ فَأَغۡرَقۡنَٰهُمۡ فِي ٱلۡيَمِّ بِأَنَّهُمۡ كَذَّبُواْ بِـَٔايَٰتِنَا وَكَانُواْ عَنۡهَا غَٰفِلِينَ ١٣٦","فانتقمنا منهم فأغرقناهم في اليم بأنهم كذبوا بآياتنا وكانوا عنها غافلين","ދެން ތިމަންރަސްކަލާނގެ އެއުރެންގެ ކިބައިން ބަދަލު ހިއްޕެވީމެވެ. އަދި ކަނޑުގެ ތެރެޔަށް އެއުރެން ޣަރަގުކުރެއްވީމެވެ. އެއީ ތިމަންރަސްކަލާނގެ އާޔަތްތައް އެއުރެން ދޮގުކޮށް، އެ އާޔަތް ތަކާމެދު ޣާފިލު ވީ ބަޔަކު ކަމުގައި ވީކަމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","137","وَأَوۡرَثۡنَا ٱلۡقَوۡمَ ٱلَّذِينَ كَانُواْ يُسۡتَضۡعَفُونَ مَشَٰرِقَ ٱلۡأَرۡضِ وَمَغَٰرِبَهَا ٱلَّتِي بَٰرَكۡنَا فِيهَاۖ وَتَمَّتۡ كَلِمَتُ رَبِّكَ ٱلۡحُسۡنَىٰ عَلَىٰ بَنِيٓ إِسۡرَـٰٓءِيلَ بِمَا صَبَرُواْۖ وَدَمَّرۡنَا مَا كَانَ يَصۡنَعُ فِرۡعَوۡنُ وَقَوۡمُهُۥ وَمَا كَانُواْ يَعۡرِشُونَ ١٣٧","وأورثنا القوم الذين كانوا يستضعفون مشارق الأرض ومغاربها التي باركنا فيها وتمت كلمت ربك الحسنى على بني إسرائيل بما صبروا ودمرنا ما كان يصنع فرعون وقومه وما كانوا يعرشون","ނިކަމެތިކޮށް ހިތެމުންދިޔަ ގައުމުގެމީހުންނަށް، ބިމުގެ އިރުމައްޗާއި، އެ ބިމުގެ ހުޅަނގު، ތިމަންރަސްކަލާނގެ ވާރުތަކޮށްދެއްވީމެވެ. އެއީ ތިމަންރަސްކަލާނގެ އެތަންތާނގައި ބަރަކާތް ލައްވާފައިވާ ތަންތަނެވެ. އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އިސްރާއީލުގެދަރިންނަށް ދެއްވާފައިވާ (ވައުދުގެ) ހެޔޮބަސްފުޅު، އެއުރެން ކެތްތެރިވުމުގެ ސަބަބުން ފުރިހަމަވެގެންދިޔައެވެ. އަދި ތިމަންރަސްކަލާނގެ، ފިރްޢައުނާއި، އޭނާގެ ގައުމުގެމީހުން ހަދަމުންގެންދިޔަ ތަކެއްޗާއި، އެއުރެން ބިނާކުރަމުންގެންދިޔަ އިމާރާތްތައް ހަލާކުކުރައްވައި، ނެތިކުރެއްވީމެވެ.","",""],["₇ سورة الأعراف","138","وَجَٰوَزۡنَا بِبَنِيٓ إِسۡرَـٰٓءِيلَ ٱلۡبَحۡرَ فَأَتَوۡاْ عَلَىٰ قَوۡمٖ يَعۡكُفُونَ عَلَىٰٓ أَصۡنَامٖ لَّهُمۡۚ قَالُواْ يَٰمُوسَى ٱجۡعَل لَّنَآ إِلَٰهٗا كَمَا لَهُمۡ ءَالِهَةٞۚ قَالَ إِنَّكُمۡ قَوۡمٞ تَجۡهَلُونَ ١٣٨","وجاوزنا ببني إسرائيل البحر فأتوا على قوم يعكفون على أصنام لهم قالوا يا موسى اجعل لنا إلها كما لهم آلهة قال إنكم قوم تجهلون","އަދި ކަނޑު ހުރަސްކުރައްވައި، ތިމަންރަސްކަލާނގެ އިސްރާއީލުގެދަރިން ގެންދެވީމެވެ. ދެން އެއުރެން ގައުމެއްގެ މީހުންނާހަމަޔަށް އައޫއެވެ. އެއުރެންތިބީ، އެއުރެންގެ ބުދުތަކަށް އަޅުކަންކުރުން މަތީގައެވެ. އެއުރެން (އެބަހީ: އިސްރާއީލުގެދަރިން) ދެންނެވޫއެވެ. އޭ މޫސާގެފާނެވެ! އެއުރެންނަށް އިލާހުންތަކެއް ވާފަދައިން، ތިމަންމެންނަށްވެސް އިލާހެއް ލައްވައި ދެއްވާށެވެ! އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނީ (ހައްގު ގޮތް) ނޭނގޭ ބަޔެކެވެ.","",""],["₇ سورة الأعراف","139","إِنَّ هَـٰٓؤُلَآءِ مُتَبَّرٞ مَّا هُمۡ فِيهِ وَبَٰطِلٞ مَّا كَانُواْ يَعۡمَلُونَ ١٣٩","إن هؤلاء متبر ما هم فيه وباطل ما كانوا يعملون","ހަމަކަށަވަރުން، އެގޮތެއްގެ މަތީގައި އެއުރެންތިބި ގޮތަކީ، ހަލާކުވެ އުވިގެންދާނޭ ގޮތެކެވެ. އަދި އެއުރެން ކޮށްއުޅުނު ޢަމަލުތައް، ބާތިލު ވެގެންވެއެވެ.","",""],["₇ سورة الأعراف","140","قَالَ أَغَيۡرَ ٱللَّهِ أَبۡغِيكُمۡ إِلَٰهٗا وَهُوَ فَضَّلَكُمۡ عَلَى ٱلۡعَٰلَمِينَ ١٤٠","قال أغير الله أبغيكم إلها وهو فضلكم على العالمين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އާލަމްތަކުގެ މައްޗަށް ތިޔަބައިމީހުން މާތްކުރެއްވީ، އެކަލާނގެ ކަމުގައިވާ ޙާލު، ތިޔަބައިމީހުންނަށް އިލާހަކު ކަމުގައި ﷲ ނޫން އެހެންފަރާތެއް ތިމަންކަލޭގެފާނު އެދިވަޑައިގަންނަވަންވީ ހެއްޔެވެ؟","",""],["₇ سورة الأعراف","141","وَإِذۡ أَنجَيۡنَٰكُم مِّنۡ ءَالِ فِرۡعَوۡنَ يَسُومُونَكُمۡ سُوٓءَ ٱلۡعَذَابِ يُقَتِّلُونَ أَبۡنَآءَكُمۡ وَيَسۡتَحۡيُونَ نِسَآءَكُمۡۚ وَفِي ذَٰلِكُم بَلَآءٞ مِّن رَّبِّكُمۡ عَظِيمٞ ١٤١","وإذ أنجيناكم من آل فرعون يسومونكم سوء العذاب يقتلون أبناءكم ويستحيون نساءكم وفي ذلكم بلاء من ربكم عظيم","ފިރްޢައުނުގެ މީހުންގެ ކިބައިން ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން މިންޖުކުރެއްވިހިނދު، ހަނދުމަކުރާށެވެ! އެއުރެން ތިޔަބައިމީހުންނަށް ގަދަފަދަވެގެންވާ އަޒާބުގެ ރަހަ ދައްކަމުން ގެންދެތެވެ. އެއުރެން ތިޔަބައިމީހުންގެ ތެރެއިން ފިރިހެންދަރިން ގަތުލު ކޮށް، އަދި ތިޔަބައިމީހުންގެ ތެރެއިން އަންހެނުން ނުމަރައި ބައިތިއްބަތެވެ. އެކަންތައްތަކުގައި، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައިސްފައިވާ ބޮޑު އިމްތިހާނެއްވެއެވެ.","",""],["₇ سورة الأعراف","142","۞وَوَٰعَدۡنَا مُوسَىٰ ثَلَٰثِينَ لَيۡلَةٗ وَأَتۡمَمۡنَٰهَا بِعَشۡرٖ فَتَمَّ مِيقَٰتُ رَبِّهِۦٓ أَرۡبَعِينَ لَيۡلَةٗۚ وَقَالَ مُوسَىٰ لِأَخِيهِ هَٰرُونَ ٱخۡلُفۡنِي فِي قَوۡمِي وَأَصۡلِحۡ وَلَا تَتَّبِعۡ سَبِيلَ ٱلۡمُفۡسِدِينَ ١٤٢","وواعدنا موسى ثلاثين ليلة وأتممناها بعشر فتم ميقات ربه أربعين ليلة وقال موسى لأخيه هارون اخلفني في قومي وأصلح ولا تتبع سبيل المفسدين","(ބަސް ވަހީކުރެއްވުމަށާއި، ތައުރާތު ބާވައިލެއްވުމަށް) ތިރީސް ރޭގެ މުއްދަތެއް ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް ކަނޑައަޅުއްވައި ދެއްވީމެވެ. އަދި އެއަށް ދިހަޔެއް އިތުރުކުރައްވައި، ފުރިހަމަ ކުރެއްވީމެވެ. ފަހެ، އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ކަނޑައަޅުއްވާފައިވާ މުއްދަތު ސާޅީސް ރޭ ފުރިހަމަވިއެވެ. އަދި މޫސާގެފާނު އެކަލޭގެފާނުގެ އަޚު، ހާރޫނުގެފާނަށް ވިދާޅުވިއެވެ. ތިމަންކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ތެރޭގައި ތިމަންކަލޭގެފާނުގެ ބަދަލުގައި ހުންނަވާށެވެ! އަދި އިސްލާހުކުރައްވާށެވެ! އަދި ފަސާދަކުރާ މީހުންގެ މަގަށް ތަބާ ވެވަޑައިނުގަންނަވާށެވެ!","",""],["₇ سورة الأعراف","143","وَلَمَّا جَآءَ مُوسَىٰ لِمِيقَٰتِنَا وَكَلَّمَهُۥ رَبُّهُۥ قَالَ رَبِّ أَرِنِيٓ أَنظُرۡ إِلَيۡكَۚ قَالَ لَن تَرَىٰنِي وَلَٰكِنِ ٱنظُرۡ إِلَى ٱلۡجَبَلِ فَإِنِ ٱسۡتَقَرَّ مَكَانَهُۥ فَسَوۡفَ تَرَىٰنِيۚ فَلَمَّا تَجَلَّىٰ رَبُّهُۥ لِلۡجَبَلِ جَعَلَهُۥ دَكّٗا وَخَرَّ مُوسَىٰ صَعِقٗاۚ فَلَمَّآ أَفَاقَ قَالَ سُبۡحَٰنَكَ تُبۡتُ إِلَيۡكَ وَأَنَا۠ أَوَّلُ ٱلۡمُؤۡمِنِينَ ١٤٣","ولما جاء موسى لميقاتنا وكلمه ربه قال رب أرني أنظر إليك قال لن تراني ولكن انظر إلى الجبل فإن استقر مكانه فسوف تراني فلما تجلى ربه للجبل جعله دكا وخر موسى صعقا فلما أفاق قال سبحانك تبت إليك وأنا أول المؤمنين","ތިމަންރަސްކަލާނގެ ކަނޑައަޅުއްވާފައިވާ މުއްދަތަށް މޫސާގެފާނު ވަޑައިގަންނަވައި، އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެކަލޭގެފާނަށް ބަސް ވަހީކުރެއްވިހިނދު، އެކަލޭގެފާނު ދެންނެވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! އިބަރަސްކަލާނގެ ޛާތު ފުޅަށް ތިމަންއަޅާ ބަލައިލުމަށްޓަކައި، ތިމަންއަޅާއަށް ދައްކަވައިފާނދޭވެ! އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ކަލޭގެފާނަކަށް ތިމަންރަސްކަލާނގެ ޛާތުފުޅު ފެނިވަޑައެއް ނުގަންނަވާނެތެވެ. އެހެނެއްކަމަކު، ފަރުބަދަޔަށް ބައްލަވާށެވެ! ފަހެ، އެ ފަރުބަދަ، އެހުރިތާ ހަރުލައިހުރެއްޖެނަމަ، ކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ ޛާތުފުޅު ފެނިވަޑައިގެންފާނެތެވެ. ފަހެ، އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ފަރުބަދަޔަށް ތަޖައްލީ ވެވޮޑިގަތްހިނދު، އެ ފަރުބަދަ ކުނޑިކުނޑިވެ ބިމާ ހަމަވެގެންވާ އެއްޗެއް ކަމުގައި ލެއްވިއެވެ. އަދި މޫސާގެފާނު، ހޭފުޅުނެތިގެން ވެއްޓިވަޑައިގެންފިއެވެ. ފަހެ، އެކަލޭގެފާނު ހޭފުޅުއެރިހިނދު ވިދާޅުވިއެވެ. އިބަރަސްކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! އިބަރަސްކަލާނގެއަށް ތިމަންއަޅާ ތައުބާ ވެއްޖައީމެވެ. އަދި އީމާންވި މީހުންކުރެ ފުރަތަމަ މީހަކީ ތިމަންއަޅާއެވެ.","",""],["₇ سورة الأعراف","144","قَالَ يَٰمُوسَىٰٓ إِنِّي ٱصۡطَفَيۡتُكَ عَلَى ٱلنَّاسِ بِرِسَٰلَٰتِي وَبِكَلَٰمِي فَخُذۡ مَآ ءَاتَيۡتُكَ وَكُن مِّنَ ٱلشَّـٰكِرِينَ ١٤٤","قال يا موسى إني اصطفيتك على الناس برسالاتي وبكلامي فخذ ما آتيتك وكن من الشاكرين","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. އޭ މޫސާގެފާނެވެ! ތިމަންރަސްކަލާނގެ ރަސޫލުކަމާއި، އަދި ބަސް ވަހީކުރެއްވުމުން މީސްތަކުންގެ މައްޗަށް ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ޚިޔާރުކުރައްވައިފީމެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ދެއްވި ކަންކަމުގައި ހިފަހައްޓަވާށެވެ! އަދި ޝުކުރުކުރާ މީހުންގެ ތެރެއިން ކަލޭގެފާނު ވެވަޑައިގަންނަވާށެވެ!","",""],["₇ سورة الأعراف","145","وَكَتَبۡنَا لَهُۥ فِي ٱلۡأَلۡوَاحِ مِن كُلِّ شَيۡءٖ مَّوۡعِظَةٗ وَتَفۡصِيلٗا لِّكُلِّ شَيۡءٖ فَخُذۡهَا بِقُوَّةٖ وَأۡمُرۡ قَوۡمَكَ يَأۡخُذُواْ بِأَحۡسَنِهَاۚ سَأُوْرِيكُمۡ دَارَ ٱلۡفَٰسِقِينَ ١٤٥","وكتبنا له في الألواح من كل شيء موعظة وتفصيلا لكل شيء فخذها بقوة وأمر قومك يأخذوا بأحسنها سأريكم دار الفاسقين","(ދީން އާބެހޭ) ކޮންމެކަމެއް (ތައުރާތުގެ) ފިލާތަކުގައި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ލިޔެދެއްވީމެވެ. ވައުޒެއްގެ ގޮތުގައެވެ. އަދި އެންމެހާ ކަންތައް ބަޔާންކޮށްދެއްވުމެއްގެ ގޮތުގައި މެއެވެ. ފަހެ، ބާރާއެކު ކަލޭގެފާނު އޭގައި ހިއްޕަވާށެވެ! އަދި އޭގައިވާ އެންމެ މޮޅުގޮތުގައި ހިފުމަށް، ކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް އަމުރުކުރައްވާށެވެ! ފާސިގު ވިމީހުންގެ ގޯތިގެދޮރު (އިބްރަތެއްގެ ގޮތުގައި) ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް ދައްކަވާހުށީމެވެ.","",""],["₇ سورة الأعراف","146","سَأَصۡرِفُ عَنۡ ءَايَٰتِيَ ٱلَّذِينَ يَتَكَبَّرُونَ فِي ٱلۡأَرۡضِ بِغَيۡرِ ٱلۡحَقِّ وَإِن يَرَوۡاْ كُلَّ ءَايَةٖ لَّا يُؤۡمِنُواْ بِهَا وَإِن يَرَوۡاْ سَبِيلَ ٱلرُّشۡدِ لَا يَتَّخِذُوهُ سَبِيلٗا وَإِن يَرَوۡاْ سَبِيلَ ٱلۡغَيِّ يَتَّخِذُوهُ سَبِيلٗاۚ ذَٰلِكَ بِأَنَّهُمۡ كَذَّبُواْ بِـَٔايَٰتِنَا وَكَانُواْ عَنۡهَا غَٰفِلِينَ ١٤٦","سأصرف عن آياتي الذين يتكبرون في الأرض بغير الحق وإن يروا كل آية لا يؤمنوا بها وإن يروا سبيل الرشد لا يتخذوه سبيلا وإن يروا سبيل الغي يتخذوه سبيلا ذلك بأنهم كذبوا بآياتنا وكانوا عنها غافلين","ހައްގަކާނުލައި ބިމުގައި ބޮޑާވެގެން އުޅޭމީހުން، ތިމަންރަސްކަލާނގެ އާޔަތް ތަކުން އެއްކިބާކުރައްވާހުށީމެވެ. އެއުރެނަށް ކޮންމެ އާޔަތެއް ފެނުނަސް، އެއަކަށް އެއުރެންނެއް އީމާނެއް ނުވެތެވެ. ރަނގަޅު ގޮތުގެ މަގު އެއުރެންނަށް ފެނުނަސް، އެއީ މަގެއްކަމުގައި އެއުރެން ނުހިފަތެވެ. އަދި ފުރެދުމުގެ މަގު އެބައިމީހުންނަށް ފެނިއްޖެނަމަ، އެއީ މަގެއްކަމުގައި އެއުރެން ހިފަތެވެ. އެއީ އެއުރެން ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކޮށް، އަދި އެ އާޔަތް ތަކާމެދު ޣާފިލު ވެގެންވާ ބަޔަކު ކަމުގައި އެއުރެން ވީކަމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","147","وَٱلَّذِينَ كَذَّبُواْ بِـَٔايَٰتِنَا وَلِقَآءِ ٱلۡأٓخِرَةِ حَبِطَتۡ أَعۡمَٰلُهُمۡۚ هَلۡ يُجۡزَوۡنَ إِلَّا مَا كَانُواْ يَعۡمَلُونَ ١٤٧","والذين كذبوا بآياتنا ولقاء الآخرة حبطت أعمالهم هل يجزون إلا ما كانوا يعملون","އަދި ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާއި، އަދި އާޚިރަތާ ބައްދަލުވާނެކަން ދޮގުކުޅަ މީހުންގެ ޢަމަލުތައް، ބާތިލު ވެގެން ހިނގައްޖެއެވެ. އެއުރެން ކޮށްއުޅުނު ކަންތަކަށްމެނުވީ، އެއުރެންނަށް ޖަޒާ ލިބޭނެހެއްޔެވެ؟","",""],["₇ سورة الأعراف","148","وَٱتَّخَذَ قَوۡمُ مُوسَىٰ مِنۢ بَعۡدِهِۦ مِنۡ حُلِيِّهِمۡ عِجۡلٗا جَسَدٗا لَّهُۥ خُوَارٌۚ أَلَمۡ يَرَوۡاْ أَنَّهُۥ لَا يُكَلِّمُهُمۡ وَلَا يَهۡدِيهِمۡ سَبِيلًاۘ ٱتَّخَذُوهُ وَكَانُواْ ظَٰلِمِينَ ١٤٨","واتخذ قوم موسى من بعده من حليهم عجلا جسدا له خوار ألم يروا أنه لا يكلمهم ولا يهديهم سبيلا اتخذوه وكانوا ظالمين","މޫސާގެފާނުގެ ގައުމުގެމީހުން، އެކަލޭގެފާނު ވަކިވެވަޑައިގަތުމަށްފަހު، ޅަގެރިޔެއްގެ ސިފާގައިވާ، އަދި އޭގެ އަޑުކަހަލަ އަޑެއްވާ ހަށިގަނޑެއް އެއުރެންގެ ގަހަނާތަކުން ހެދޫއެވެ. އެ ގެރި، އެއުރެންނާ ވާހަކަނުދައްކާކަމާއި، އަދި އެއްވެސް މަގަކަށް އެއުރެންނަށް މަގުނުދައްކާކަން އެއުރެން ނުދެކެނީހެއްޔެވެ؟ އެއުރެން އެގެރި (އިލާހެއްކަމުގައި) ހިފައިފޫއެވެ. އަދި އަނިޔާވެރިންކަމުގައި އެއުރެންވޫއެވެ.","",""],["₇ سورة الأعراف","149","وَلَمَّا سُقِطَ فِيٓ أَيۡدِيهِمۡ وَرَأَوۡاْ أَنَّهُمۡ قَدۡ ضَلُّواْ قَالُواْ لَئِن لَّمۡ يَرۡحَمۡنَا رَبُّنَا وَيَغۡفِرۡ لَنَا لَنَكُونَنَّ مِنَ ٱلۡخَٰسِرِينَ ١٤٩","ولما سقط في أيديهم ورأوا أنهم قد ضلوا قالوا لئن لم يرحمنا ربنا ويغفر لنا لنكونن من الخاسرين","އެއުރެން (އެކުޅަ ކަންތަކާމެދު) ދެރަވެ، ހިތާމަލިބި، އަދި އެއުރެންނަށް މަގު އޮޅިއްޖެކަމަށް ފެނުނުހިނދު، އެއުރެން ބުނޫއެވެ. ތިމަންމެންގެ ވެރިރަސްކަލާނގެ، ތިމަންމެންނަށް ރަހުމަތް ނުލެއްވިނަމަ، އަދި ތިމަންމެންނަށް ފާފަފުއްސަވައި ނުދެއްވިނަމަ، ހަމަކަށަވަރުން، ތިމަންމެންވާހުށީ، ގެއްލެނިވެގެންވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["₇ سورة الأعراف","150","وَلَمَّا رَجَعَ مُوسَىٰٓ إِلَىٰ قَوۡمِهِۦ غَضۡبَٰنَ أَسِفٗا قَالَ بِئۡسَمَا خَلَفۡتُمُونِي مِنۢ بَعۡدِيٓۖ أَعَجِلۡتُمۡ أَمۡرَ رَبِّكُمۡۖ وَأَلۡقَى ٱلۡأَلۡوَاحَ وَأَخَذَ بِرَأۡسِ أَخِيهِ يَجُرُّهُۥٓ إِلَيۡهِۚ قَالَ ٱبۡنَ أُمَّ إِنَّ ٱلۡقَوۡمَ ٱسۡتَضۡعَفُونِي وَكَادُواْ يَقۡتُلُونَنِي فَلَا تُشۡمِتۡ بِيَ ٱلۡأَعۡدَآءَ وَلَا تَجۡعَلۡنِي مَعَ ٱلۡقَوۡمِ ٱلظَّـٰلِمِينَ ١٥٠","ولما رجع موسى إلى قومه غضبان أسفا قال بئسما خلفتموني من بعدي أعجلتم أمر ربكم وألقى الألواح وأخذ برأس أخيه يجره إليه قال ابن أم إن القوم استضعفوني وكادوا يقتلونني فلا تشمت بي الأعداء ولا تجعلني مع القوم الظالمين","އަދި މޫސާގެފާނު ކޯފާވެ، ހިތާމަކުރައްވާ ޙާލު، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ގާތަށް ވަޑައިގަތްހިނދު، ވިދާޅުވިއެވެ. ތިމަންކަލޭގެފާނު ތިޔަބައިމީހުންނާ ވަކިވެގެން ދިއުމަށްފަހު، ތިމަންކަލޭގެފާނުގެ ފަހަތުން ތިޔަބައިމީހުން ކުޅަކަންތަކުގެ ނުބައިކަމާއެވެ! ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ އަމުރުފުޅު އައުމަށް ތިޔަބައިމީހުން އަވަސްވެގަތީހެއްޔެވެ؟ އަދި އެކަލޭގެފާނު (ތައުރާތުގެ) ފިލާތައް އުއްކަވައިލެއްވިއެވެ. އަދި އެކަލޭގެފާނުގެ އަޚުގެ އިސްތަށިފުޅުގައި ހިއްޕަވައި އެކަލޭގެފާނުގެ އަރިހަށް ދަންމަވައިގެންނެވިއެވެ. އެކަލޭގެފާނު (އެބަހީ: ހާރޫނުގެފާނު) ވިދާޅުވިއެވެ. މަންމަގެ ދަރިކަލުންނޭވެ! ހަމަކަށަވަރުން، ގައުމުގެމީހުން ތިމަން ނިކަމެތިކޮށްފޫއެވެ. އަދި އެއުރެން ތިމަން ގަތުލުކުރުމާ ގާތްކޮށްފޫއެވެ. ފަހެ، ތިމަންކަލޭގެފާނަށް ލިބިވަޑައިގެންނެވި ދެރަޔަށް އަދާވަތް ތެރިން އުފާކުރިޔަ ނުދެއްވާށެވެ! އަދި އަނިޔާވެރިވީ މީހުންނާއެކުގައި، ތިމަން ނުލައްވާށެވެ!","",""],["₇ سورة الأعراف","151","قَالَ رَبِّ ٱغۡفِرۡ لِي وَلِأَخِي وَأَدۡخِلۡنَا فِي رَحۡمَتِكَۖ وَأَنتَ أَرۡحَمُ ٱلرَّـٰحِمِينَ ١٥١","قال رب اغفر لي ولأخي وأدخلنا في رحمتك وأنت أرحم الراحمين","އެކަލޭގެފާނު (އެބަހީ: މޫސާގެފާނު) ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ތިމަންއަޅާއަށާއި، ތިމަންއަޅާގެ އަޚާއަށް ފާފަފުއްސަވާނދޭވެ! އަދި އިބަރަސްކަލާނގެ ރަހުމަތްގެ ތެރެޔަށް އަޅަމެން ވައްދަވައިފާނދޭވެ! އިބަރަސްކަލާނގެއީ، ރަހުމަތް ލައްވާ އެންމެ ރަހުމަތްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₇ سورة الأعراف","152","إِنَّ ٱلَّذِينَ ٱتَّخَذُواْ ٱلۡعِجۡلَ سَيَنَالُهُمۡ غَضَبٞ مِّن رَّبِّهِمۡ وَذِلَّةٞ فِي ٱلۡحَيَوٰةِ ٱلدُّنۡيَاۚ وَكَذَٰلِكَ نَجۡزِي ٱلۡمُفۡتَرِينَ ١٥٢","إن الذين اتخذوا العجل سينالهم غضب من ربهم وذلة في الحياة الدنيا وكذلك نجزي المفترين","ހަމަކަށަވަރުން، ގެރިޔަކީ، އިލާހެއްކަމުގައި ހަދައިގެން އުޅުނުމީހުންނަށް، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ކޯފާއާއި، ދުނިޔޭގެ ދިރިއުޅުމުގައި ނިކަމެތިކަން ލިބޭހުށްޓެވެ. އަދި ދޮގު އުފައްދާ މީހުންނަށް ތިމަންރަސްކަލާނގެ ޖަޒާ ދެއްވަނީ އެފަދައިންނެވެ.","",""],["₇ سورة الأعراف","153","وَٱلَّذِينَ عَمِلُواْ ٱلسَّيِّـَٔاتِ ثُمَّ تَابُواْ مِنۢ بَعۡدِهَا وَءَامَنُوٓاْ إِنَّ رَبَّكَ مِنۢ بَعۡدِهَا لَغَفُورٞ رَّحِيمٞ ١٥٣","والذين عملوا السيئات ثم تابوا من بعدها وآمنوا إن ربك من بعدها لغفور رحيم","އަދި ނުބައިކަންތައްކޮށް ދެން އެއަށްފަހު، ތައުބާވެ، އީމާންވި މީހުން (ދަންނާށެވެ!) ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، އޭގެފަހުންވެސް ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["₇ سورة الأعراف","154","وَلَمَّا سَكَتَ عَن مُّوسَى ٱلۡغَضَبُ أَخَذَ ٱلۡأَلۡوَاحَۖ وَفِي نُسۡخَتِهَا هُدٗى وَرَحۡمَةٞ لِّلَّذِينَ هُمۡ لِرَبِّهِمۡ يَرۡهَبُونَ ١٥٤","ولما سكت عن موسى الغضب أخذ الألواح وفي نسختها هدى ورحمة للذين هم لربهم يرهبون","މޫސާގެފާނުގެ ކިބައިން ކޯފާމަޑުވިހިނދު (ތައުރާތުގެ) ފިލާތައް ނެންގެވިއެވެ. އަދި އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ބިރުވެތިވާ މީހުންނަށްޓަކައި ހުރި ތެދުމަގާއި، ރަހުމަތް، އެ ފިލާތަކުގެ ލިޔުމުގައި ވެއެވެ.","",""],["₇ سورة الأعراف","155","وَٱخۡتَارَ مُوسَىٰ قَوۡمَهُۥ سَبۡعِينَ رَجُلٗا لِّمِيقَٰتِنَاۖ فَلَمَّآ أَخَذَتۡهُمُ ٱلرَّجۡفَةُ قَالَ رَبِّ لَوۡ شِئۡتَ أَهۡلَكۡتَهُم مِّن قَبۡلُ وَإِيَّـٰيَۖ أَتُهۡلِكُنَا بِمَا فَعَلَ ٱلسُّفَهَآءُ مِنَّآۖ إِنۡ هِيَ إِلَّا فِتۡنَتُكَ تُضِلُّ بِهَا مَن تَشَآءُ وَتَهۡدِي مَن تَشَآءُۖ أَنتَ وَلِيُّنَا فَٱغۡفِرۡ لَنَا وَٱرۡحَمۡنَاۖ وَأَنتَ خَيۡرُ ٱلۡغَٰفِرِينَ ١٥٥","واختار موسى قومه سبعين رجلا لميقاتنا فلما أخذتهم الرجفة قال رب لو شئت أهلكتهم من قبل وإياي أتهلكنا بما فعل السفهاء منا إن هي إلا فتنتك تضل بها من تشاء وتهدي من تشاء أنت ولينا فاغفر لنا وارحمنا وأنت خير الغافرين","އަދި ތިމަންރަސްކަލާނގެ ކަނޑައަޅުއްވާފައިވާ ވަގުތަށްޓަކައި މޫސާގެފާނު އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ތެރެއިން ހަތްދިހަ ފިރިހެނުން ހޮއްވެވިއެވެ. ފަހެ، ގަދަފަދަވެގެންވާ ބިންހެލުން އެއުރެންނަށް ޖެހުނުހިނދު، އެކަލޭގެފާނު ދެންނެވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! އިބަރަސްކަލާނގެ އިރާދަކުރެއްވިނަމަ، މީގެކުރިންވެސް އެއުރެންނާއި ތިމަންއަޅާ ހަލާކުކުރައްވައިފީހެވެ. އަޅަމެންގެ ތެރެއިން ހަމަބުއްދި ނުވާމީހުން ކުޅަކަންތަކުގެ ސަބަބުން، އަޅަމެން ހަލާކު ކުރައްވަނީތޯއެވެ؟ އިބަރަސްކަލާނގެ ފޮނުއްވި އިމްތިހާނެއްކަމުގައިނޫނީ އެކަންތައް ނުވެތެވެ. އެކަމުގެ ސަބަބުން، އިބަރަސްކަލާނގެ އިރާދަކުރައްވާ މީހަކު ފުރައްދަވަމުއެވެ. އަދި އިރާދަކުރައްވާ މީހަކަށް ތެދުމަގު ދައްކަވަމުއެވެ. އިބަރަސްކަލާނގެއީ، އަޅަމެންގެ އެހީތެރިވަންތަ ރަސްކަލާނގެއެވެ. ފަހެ، އަޅަމެންނަށް ފާފަފުއްސަވާނދޭވެ! އަދި އަޅަމެންނަށް ރަހުމަތް ލައްވައިފާނދޭވެ! އިބަރަސްކަލާނގެއީ، ފާފަފުއްސަވާ، އެންމެހެޔޮ ރަސްކަލާނގެއެވެ.","",""],["₇ سورة الأعراف","156","۞وَٱكۡتُبۡ لَنَا فِي هَٰذِهِ ٱلدُّنۡيَا حَسَنَةٗ وَفِي ٱلۡأٓخِرَةِ إِنَّا هُدۡنَآ إِلَيۡكَۚ قَالَ عَذَابِيٓ أُصِيبُ بِهِۦ مَنۡ أَشَآءُۖ وَرَحۡمَتِي وَسِعَتۡ كُلَّ شَيۡءٖۚ فَسَأَكۡتُبُهَا لِلَّذِينَ يَتَّقُونَ وَيُؤۡتُونَ ٱلزَّكَوٰةَ وَٱلَّذِينَ هُم بِـَٔايَٰتِنَا يُؤۡمِنُونَ ١٥٦","واكتب لنا في هذه الدنيا حسنة وفي الآخرة إنا هدنا إليك قال عذابي أصيب به من أشاء ورحمتي وسعت كل شيء فسأكتبها للذين يتقون ويؤتون الزكاة والذين هم بآياتنا يؤمنون","އަދި އަޅަމެންނަށްޓަކައި މިދުނިޔޭގައިވެސް، އަދި އާޚިރަތް ގައިވެސް ހެޔޮގޮތް ލިޔުއްވައިފާނދޭވެ! ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެ ހަޒުރަތަށް އަޅަމެން ރުޖޫއަ ވެއްޖައީމުއެވެ. އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ތިމަންރަސްކަލާނގެ އަޒާބެވެ. ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް އެ އަޒާބުކުރިމަތި ކުރައްވަމެވެ. އަދި ތިމަންރަސްކަލާނގެ ރަހުމަތް ކޮންމެ އެއްޗަކަށްމެ ތަނަވަސް ވެގެންވެއެވެ. ފަހެ، ތަގުވާވެރިވެ، ޒަކާތް ދީ އުޅޭމީހުންނަށާއި، ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް އީމާންވާ މީހުންނަށް ތިމަންރަސްކަލާނގެ އެ ރަހުމަތް ލިޔުއްވާހުށީމެވެ.","",""],["₇ سورة الأعراف","157","ٱلَّذِينَ يَتَّبِعُونَ ٱلرَّسُولَ ٱلنَّبِيَّ ٱلۡأُمِّيَّ ٱلَّذِي يَجِدُونَهُۥ مَكۡتُوبًا عِندَهُمۡ فِي ٱلتَّوۡرَىٰةِ وَٱلۡإِنجِيلِ يَأۡمُرُهُم بِٱلۡمَعۡرُوفِ وَيَنۡهَىٰهُمۡ عَنِ ٱلۡمُنكَرِ وَيُحِلُّ لَهُمُ ٱلطَّيِّبَٰتِ وَيُحَرِّمُ عَلَيۡهِمُ ٱلۡخَبَـٰٓئِثَ وَيَضَعُ عَنۡهُمۡ إِصۡرَهُمۡ وَٱلۡأَغۡلَٰلَ ٱلَّتِي كَانَتۡ عَلَيۡهِمۡۚ فَٱلَّذِينَ ءَامَنُواْ بِهِۦ وَعَزَّرُوهُ وَنَصَرُوهُ وَٱتَّبَعُواْ ٱلنُّورَ ٱلَّذِيٓ أُنزِلَ مَعَهُۥٓ أُوْلَـٰٓئِكَ هُمُ ٱلۡمُفۡلِحُونَ ١٥٧","الذين يتبعون الرسول النبي الأمي الذي يجدونه مكتوبا عندهم في التوراة والإنجيل يأمرهم بالمعروف وينهاهم عن المنكر ويحل لهم الطيبات ويحرم عليهم الخبائث ويضع عنهم إصرهم والأغلال التي كانت عليهم فالذين آمنوا به وعزروه ونصروه واتبعوا النور الذي أنزل معه أولئك هم المفلحون","އެއުރެންނީ، އުއްމީ ނަބިއްޔާ ކަމުގައިވާ ރަސޫލާއަށް ތަބާވާ މީހުންނެވެ. އެ ރަސޫލާއި، އެއުރެންގެ ގާތުގައިވާ ތައުރާތާއި، އިންޖީލުގައި (ރަސޫލާގެ ސިފަފުޅުތައް) ލިޔެވިގެންވާތީ، އެއުރެންދެކޭ ރަސޫލެވެ. އެކަލޭގެފާނު، އެއުރެންނަށް ހެޔޮކަންތަކަށް އަމުރުކުރައްވަތެވެ. އަދި ނުބައިކަންތައް އެއުރެންނަށް ނަހީކުރައްވަތެވެ. އަދި ރަނގަޅު ތަކެތި އެއުރެންނަށް ހަލާލުކުރައްވަތެވެ. އަދި ނުބައިވެގެންވާ ތަކެތި އެއުރެންނަށް ހަރާމްކުރައްވަތެވެ. އަދި އެއުރެންގެ މައްޗަށްހުރި ބުރަތަކާއި، އެއުރެންގައި އެޅިފައިވާ ކަސްތޮޅުތައް ނެތިކުރައްވައި، ލުއިކުރައްވަތެވެ. ފަހެ، އެކަލޭގެފާނަށް އީމާންވެ، އެކަލޭގެފާނަށް ވާގިވެރިވެ، ނަސްރުވެރިވެ، އެކަލޭގެފާނާއެކުގައި ބާވައިލެއްވި ނޫރަށް ތަބާ ވީ މީހުން (ދަންނާށެވެ!) ދިންނަވާނޭ މީހުންނަކީ، ހަމަ އެއުރެންނެވެ.","",""],["₇ سورة الأعراف","158","قُلۡ يَـٰٓأَيُّهَا ٱلنَّاسُ إِنِّي رَسُولُ ٱللَّهِ إِلَيۡكُمۡ جَمِيعًا ٱلَّذِي لَهُۥ مُلۡكُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِۖ لَآ إِلَٰهَ إِلَّا هُوَ يُحۡيِۦ وَيُمِيتُۖ فَـَٔامِنُواْ بِٱللَّهِ وَرَسُولِهِ ٱلنَّبِيِّ ٱلۡأُمِّيِّ ٱلَّذِي يُؤۡمِنُ بِٱللَّهِ وَكَلِمَٰتِهِۦ وَٱتَّبِعُوهُ لَعَلَّكُمۡ تَهۡتَدُونَ ١٥٨","قل يا أيها الناس إني رسول الله إليكم جميعا الذي له ملك السماوات والأرض لا إله إلا هو يحيي ويميت فآمنوا بالله ورسوله النبي الأمي الذي يؤمن بالله وكلماته واتبعوه لعلكم تهتدون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ މީސްތަކުންނޭވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނީ، ތިޔަބައިމީހުން އެންމެންގެ ގާތަށް ﷲ ފޮނުއްވި ރަސޫލާއެވެ. އެކަލާނގެއީ، އުޑުތަކާއި ބިމުގެ ވެރިކަން އެކަލާނގެއަށް މަލަކަ ވެގެންވާ ރަސްކަލާނގެއެވެ. އެކަލާނގެ މެނުވީ އިލާހަކު ނުވެއެވެ. ދިރުއްވަނީވެސް އަދި މަރުގަންނަވަނީވެސް، އެކަލާނގެއެވެ. ފަހެ، ﷲއަށާއި އުއްމީ ނަބިއްޔާ ކަމުގައިވާ އެކަލާނގެ ރަސޫލާއަށް ތިޔަބައިމީހުން އީމާން ވާށެވެ! އެކަލޭގެފާނީ ﷲއަށާއި އެކަލާނގެ ބަސްފުޅުތަކަށް އީމާންވާ ނަބިއްޔާއެވެ. އަދި ތިޔަބައިމީހުން، އެކަލޭގެފާނަށް ތަބާ ވާށެވެ! (އެއީ) ތިޔަބައިމީހުން ތެދުމަގު ލިބިގަތުމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","159","وَمِن قَوۡمِ مُوسَىٰٓ أُمَّةٞ يَهۡدُونَ بِٱلۡحَقِّ وَبِهِۦ يَعۡدِلُونَ ١٥٩","ومن قوم موسى أمة يهدون بالحق وبه يعدلون","ހައްގު ގޮތުގައި ތެދުމަގު ދައްކައި، އަދި ހައްގު ގޮތުގައި އިންޞާފު ކޮށްއުޅޭ ބަޔަކު، މޫސާގެފާނުގެ ގައުމުގެމީހުންގެ ތެރެއިންވެއެވެ.","",""],["₇ سورة الأعراف","160","وَقَطَّعۡنَٰهُمُ ٱثۡنَتَيۡ عَشۡرَةَ أَسۡبَاطًا أُمَمٗاۚ وَأَوۡحَيۡنَآ إِلَىٰ مُوسَىٰٓ إِذِ ٱسۡتَسۡقَىٰهُ قَوۡمُهُۥٓ أَنِ ٱضۡرِب بِّعَصَاكَ ٱلۡحَجَرَۖ فَٱنۢبَجَسَتۡ مِنۡهُ ٱثۡنَتَا عَشۡرَةَ عَيۡنٗاۖ قَدۡ عَلِمَ كُلُّ أُنَاسٖ مَّشۡرَبَهُمۡۚ وَظَلَّلۡنَا عَلَيۡهِمُ ٱلۡغَمَٰمَ وَأَنزَلۡنَا عَلَيۡهِمُ ٱلۡمَنَّ وَٱلسَّلۡوَىٰۖ كُلُواْ مِن طَيِّبَٰتِ مَا رَزَقۡنَٰكُمۡۚ وَمَا ظَلَمُونَا وَلَٰكِن كَانُوٓاْ أَنفُسَهُمۡ يَظۡلِمُونَ ١٦٠","وقطعناهم اثنتي عشرة أسباطا أمما وأوحينا إلى موسى إذ استسقاه قومه أن اضرب بعصاك الحجر فانبجست منه اثنتا عشرة عينا قد علم كل أناس مشربهم وظللنا عليهم الغمام وأنزلنا عليهم المن والسلوى كلوا من طيبات ما رزقناكم وما ظلمونا ولكن كانوا أنفسهم يظلمون","އަދި ބާރަ ގަބީލާއަށް، ޖަމާއަތް ތަކަކަށް، ތިމަންރަސްކަލާނގެ އެއުރެން ބައިކުރެއްވީމެވެ. އަދި މޫސާގެފާނުގެ ގައުމުގެމީހުން އެކަލޭގެފާނުގެ އަރިހުން ފެނަށް އެދުނުހިނދު، ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް ވަހީކުރެއްވީމެވެ. ކަލޭގެފާނުގެ އަސާކޮޅުން ހިލައިގައި ޖައްސަވާށެވެ! ދެން (އެކަލޭގެފާނު އެ ހިލައިގައި ޖެއްސެވި ހިނދު) އެ ހިލައިން ބާރަ ފެންއާރު އަރައިގެންފިއެވެ. ހަމަކަށަވަރުން، ކޮންމެބަޔަކު، އެބަޔަކު ފެންބޯންވީ ޖާގަ ދެނެގެންފޫއެވެ. އަދި ވިލާގަނޑުން، އެއުރެންގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ހިޔާއެޅުއްވީމެވެ. އަދި އެއުރެންގެ މައްޗަށް، ތިމަންރަސްކަލާނގެ މައްނާއި ސަލްވާ ބާވައިލެއްވީމެވެ. (އަދި އެންގެވީމެވެ.) ތިޔަބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ ދެއްވި ރަނގަޅު ތަކެތިން، ތިޔަބައިމީހުން ކައިއުޅޭށެވެ! އެއުރެން ތިމަންރަސްކަލާނގެއަކަށް އަނިޔާވެރިއެއް ނުވެތެވެ. އެހެނެއްކަމަކު، އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް، އަނިޔާވެރިވާ ކަމުގައި އެއުރެންވޫއެވެ.","",""],["₇ سورة الأعراف","161","وَإِذۡ قِيلَ لَهُمُ ٱسۡكُنُواْ هَٰذِهِ ٱلۡقَرۡيَةَ وَكُلُواْ مِنۡهَا حَيۡثُ شِئۡتُمۡ وَقُولُواْ حِطَّةٞ وَٱدۡخُلُواْ ٱلۡبَابَ سُجَّدٗا نَّغۡفِرۡ لَكُمۡ خَطِيٓـَٰٔتِكُمۡۚ سَنَزِيدُ ٱلۡمُحۡسِنِينَ ١٦١","وإذ قيل لهم اسكنوا هذه القرية وكلوا منها حيث شئتم وقولوا حطة وادخلوا الباب سجدا نغفر لكم خطيئاتكم سنزيد المحسنين","އެއުރެންނަށް އެންގެވިހިނދު ހަނދުމަކުރާށެވެ! ތިޔަބައިމީހުން، މިރަށުގައި ވަޒަންވެރިވެ ތިބޭށެވެ! އަދި އެރަށުން ތިޔަބައިމީހުން އެދޭފަދަޔަކުން ކައިއުޅޭށެވެ! އަދި އަޅަމެންގެ އެދުމަކީ، ކުށްފާފަތައް ފުއްސަވައި، އަފޫކުރެއްވުމޭ ދަންނަވާށެވެ! އަދި ސަޖިދަކުރާ ޙާލު، ތިޔަބައިމީހުން (އެރަށުގެ) ދޮރޯށިން ވަންނާށެވެ! އޭރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށްޓަކައި، ތިޔަބައިމީހުންގެ ކުށްފާފަތައް ފުއްސަވާހުށީމެވެ. އިހްސާން ތެރިންނަށް ތިމަންރަސްކަލާނގެ (ހެޔޮކަން) އިތުރުކުރައްވާ ހުށީމެވެ.","",""],["₇ سورة الأعراف","162","فَبَدَّلَ ٱلَّذِينَ ظَلَمُواْ مِنۡهُمۡ قَوۡلًا غَيۡرَ ٱلَّذِي قِيلَ لَهُمۡ فَأَرۡسَلۡنَا عَلَيۡهِمۡ رِجۡزٗا مِّنَ ٱلسَّمَآءِ بِمَا كَانُواْ يَظۡلِمُونَ ١٦٢","فبدل الذين ظلموا منهم قولا غير الذي قيل لهم فأرسلنا عليهم رجزا من السماء بما كانوا يظلمون","ދެން އޭގެތެރެއިން އަނިޔާވެރިވި މީހުން، އެއުރެންނަށް ކިޔާށޭ އެންގެވި ބަސް، އެނޫންބަހަކަށް ބަދަލުކޮށްފޫއެވެ. ދެން އެއުރެން އަނިޔާވެރިވެ އުޅުނުކަމުގެ ސަބަބުން، ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް އުޑުން އަޒާބެއް ފޮނުއްވީމެވެ.","",""],["₇ سورة الأعراف","163","وَسۡـَٔلۡهُمۡ عَنِ ٱلۡقَرۡيَةِ ٱلَّتِي كَانَتۡ حَاضِرَةَ ٱلۡبَحۡرِ إِذۡ يَعۡدُونَ فِي ٱلسَّبۡتِ إِذۡ تَأۡتِيهِمۡ حِيتَانُهُمۡ يَوۡمَ سَبۡتِهِمۡ شُرَّعٗا وَيَوۡمَ لَا يَسۡبِتُونَ لَا تَأۡتِيهِمۡۚ كَذَٰلِكَ نَبۡلُوهُم بِمَا كَانُواْ يَفۡسُقُونَ ١٦٣","واسألهم عن القرية التي كانت حاضرة البحر إذ يعدون في السبت إذ تأتيهم حيتانهم يوم سبتهم شرعا ويوم لا يسبتون لا تأتيهم كذلك نبلوهم بما كانوا يفسقون","އަދި ކަނޑުގެ އައްސޭރީގައިއޮތް ރަށާމެދު، ކަލޭގެފާނު އެއުރެންނާ ސުވާލުކުރައްވާށެވެ! (އެއީ) ހޮނިހިރާމެދު އެއުރެން އަދާވަތް ތެރިވަމުންދިޔަ ހިނދެވެ. އެއުރެންގެ މަސްތައް، އެއުރެންގެ ހޮނިހިރުދުވަހު ފާޅުވެ، ފެނިގެން އެއުރެންނާ ހަމަޔަށް އަންނަހިނދެވެ. އަދި އެއުރެން ހޮނިހިރު ނުކުރާދުވަހު، އެ މަސްތައް އެއުރެންނާ ހަމަޔަކަށް ނާދެއެވެ. އެފަދައިން ތިމަންރަސްކަލާނގެ އެއުރެން އިމްތިހާނުކުރައްވަމެވެ. (އެއީ) އެއުރެން ފާސިގުވެ އުޅުނުކަމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","164","وَإِذۡ قَالَتۡ أُمَّةٞ مِّنۡهُمۡ لِمَ تَعِظُونَ قَوۡمًا ٱللَّهُ مُهۡلِكُهُمۡ أَوۡ مُعَذِّبُهُمۡ عَذَابٗا شَدِيدٗاۖ قَالُواْ مَعۡذِرَةً إِلَىٰ رَبِّكُمۡ وَلَعَلَّهُمۡ يَتَّقُونَ ١٦٤","وإذ قالت أمة منهم لم تعظون قوما الله مهلكهم أو معذبهم عذابا شديدا قالوا معذرة إلى ربكم ولعلهم يتقون","އޭގެތެރެއިން އެއްބަޔަކު ބުނިހިނދެވެ. ﷲ، އެބަޔަކު ހަލާކު ކުރައްވަން، ނުވަތަ ގަދަވެގެންވާ އަޒާބަކުން އަޒާބު ދެއްވަންވެފައިވާ ބަޔަކަށް، ތިޔަބައިމީހުން ވައުޒު އިއްވަނީ ކީއްވެގެން ހެއްޔެވެ؟ އެއުރެން ބުނޫއެވެ. ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް އުޒުރު ހުށަހެޅުމުގެ ގޮތުންނެވެ. އަދި އެއުރެން ތަގުވާވެރި ވުމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","165","فَلَمَّا نَسُواْ مَا ذُكِّرُواْ بِهِۦٓ أَنجَيۡنَا ٱلَّذِينَ يَنۡهَوۡنَ عَنِ ٱلسُّوٓءِ وَأَخَذۡنَا ٱلَّذِينَ ظَلَمُواْ بِعَذَابِۭ بَـِٔيسِۭ بِمَا كَانُواْ يَفۡسُقُونَ ١٦٥","فلما نسوا ما ذكروا به أنجينا الذين ينهون عن السوء وأخذنا الذين ظلموا بعذاب بئيس بما كانوا يفسقون","ފަހެ، އެއުރެންނަށް ހަނދުމަކޮށްދެއްވި ކަންތައް އެއުރެން ހަނދާންނައްތައިލި ހިނދު، ނުބައިކަންތައް ނަހީކޮށް އުޅޭމީހުން، ތިމަންރަސްކަލާނގެ މިންޖުކުރެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ ގަދަފަދަވެގެންވާ އަޒާބަކުން އަނިޔާވެރިވީ މީހުން ހިއްޕެވީމެވެ. (އެއީ) އެއުރެން ފާސިގުވެ އުޅުނުކަމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","166","فَلَمَّا عَتَوۡاْ عَن مَّا نُهُواْ عَنۡهُ قُلۡنَا لَهُمۡ كُونُواْ قِرَدَةً خَٰسِـِٔينَ ١٦٦","فلما عتوا عن ما نهوا عنه قلنا لهم كونوا قردة خاسئين","ފަހެ، އެއުރެންނަށް ނަހީކުރެއްވި ކަންތަކާމެދު، އެއުރެން ބޮޑާވެގަތްހިނދު، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ވަހީކުރެއްވީމެވެ. ދެރަވެ، ނިކަމެތިވެގެންވާ ރާމާމަކުނުތަކެއް ކަމުގައި ތިޔަބައިމީހުންވާށެވެ!","",""],["₇ سورة الأعراف","167","وَإِذۡ تَأَذَّنَ رَبُّكَ لَيَبۡعَثَنَّ عَلَيۡهِمۡ إِلَىٰ يَوۡمِ ٱلۡقِيَٰمَةِ مَن يَسُومُهُمۡ سُوٓءَ ٱلۡعَذَابِۗ إِنَّ رَبَّكَ لَسَرِيعُ ٱلۡعِقَابِ وَإِنَّهُۥ لَغَفُورٞ رَّحِيمٞ ١٦٧","وإذ تأذن ربك ليبعثن عليهم إلى يوم القيامة من يسومهم سوء العذاب إن ربك لسريع العقاب وإنه لغفور رحيم","އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެންގެވިހިނދު ހަނދުމަކުރާށެވެ! ހަމަކަށަވަރުން، އެއުރެންނަށް ނުބައިވެގެންވާ އަޒާބުގެ ރަހަ ދައްކާނޭ ބަޔަކު ގިޔާމަތް ދުވަހަށް ދާނދެން އެކަލާނގެ އެއުރެންގެ މައްޗަށް ފޮނުއްވާހުށްޓެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ޢިގާބު ދެއްވުން އަވަސްވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އަދި ހަމަކަށަވަރުން، އެކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₇ سورة الأعراف","168","وَقَطَّعۡنَٰهُمۡ فِي ٱلۡأَرۡضِ أُمَمٗاۖ مِّنۡهُمُ ٱلصَّـٰلِحُونَ وَمِنۡهُمۡ دُونَ ذَٰلِكَۖ وَبَلَوۡنَٰهُم بِٱلۡحَسَنَٰتِ وَٱلسَّيِّـَٔاتِ لَعَلَّهُمۡ يَرۡجِعُونَ ١٦٨","وقطعناهم في الأرض أمما منهم الصالحون ومنهم دون ذلك وبلوناهم بالحسنات والسيئات لعلهم يرجعون","އަދި ބިމުގައި ތިމަންރަސްކަލާނގެ އެއުރެން އުއްމަތް ތަކަކަށް ބައިބައިކުރެއްވީމެވެ. އެއުރެންގެ ތެރެއިން ހެޔޮލަފާ މީހުންވެއެވެ. އަދި އެނޫންމީހުންވެސް އެއުރެންގެ ތެރެއިންވެއެވެ. ހެޔޮގޮތްތަކާއި، ނުބައިގޮތްތައް މެދުވެރިކުރެއްވުމުން، ތިމަންރަސްކަލާނގެ އެއުރެން އިމްތިހާނުކުރެއްވީމެވެ. (އެއީ) އެއުރެން (ހެޔޮމަގަށް) އެނބުރި އައުމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","169","فَخَلَفَ مِنۢ بَعۡدِهِمۡ خَلۡفٞ وَرِثُواْ ٱلۡكِتَٰبَ يَأۡخُذُونَ عَرَضَ هَٰذَا ٱلۡأَدۡنَىٰ وَيَقُولُونَ سَيُغۡفَرُ لَنَا وَإِن يَأۡتِهِمۡ عَرَضٞ مِّثۡلُهُۥ يَأۡخُذُوهُۚ أَلَمۡ يُؤۡخَذۡ عَلَيۡهِم مِّيثَٰقُ ٱلۡكِتَٰبِ أَن لَّا يَقُولُواْ عَلَى ٱللَّهِ إِلَّا ٱلۡحَقَّ وَدَرَسُواْ مَا فِيهِۗ وَٱلدَّارُ ٱلۡأٓخِرَةُ خَيۡرٞ لِّلَّذِينَ يَتَّقُونَۚ أَفَلَا تَعۡقِلُونَ ١٦٩","فخلف من بعدهم خلف ورثوا الكتاب يأخذون عرض هذا الأدنى ويقولون سيغفر لنا وإن يأتهم عرض مثله يأخذوه ألم يؤخذ عليهم ميثاق الكتاب أن لا يقولوا على الله إلا الحق ودرسوا ما فيه والدار الآخرة خير للذين يتقون أفلا تعقلون","ފަހެ، ފޮތް ވާރުތަވީ ބަޔަކު އެއުރެންގެ ފަހުން އައޫއެވެ. އެއުރެން މިދުނިޔޭގެ މުދަލުގައި ހިފަތެވެ. އަދި އެއުރެން ބުނެތެވެ. ތިމަންމެންނަށް ފާފަފުއްސަވާނެތެވެ. އަދި ހަމައެފަދަ މުދަލެއް، އެއުރެންނާ ހަމަޔަށް އަޔަސް އޭގައި އެއުރެން ހިފަތެވެ. ﷲއާމެދު ހައްގު ބަސްމެނުވީ އެއުރެން ނުބުނުމަށް، ފޮތުގެ ކަށަވަރުވެގެންވާ އަހުދެއުރެންގެ މައްޗަށް ނުހިއްޕަވާ ހެއްޔެވެ؟ އަދި އެފޮތުގައިވާގޮތް އެއުރެން އުނގެނި ދަސްކުރޫއެވެ. އަދި ތަގުވާވެރިވާ މީހުންނަށް އާޚިރަތްގެ ގޮވަތި މާހެޔޮކަން ބޮޑެވެ. ފަހެ، ތިޔަބައިމީހުންނަކަށް ނުވިސްނޭހެއްޔެވެ؟","",""],["₇ سورة الأعراف","170","وَٱلَّذِينَ يُمَسِّكُونَ بِٱلۡكِتَٰبِ وَأَقَامُواْ ٱلصَّلَوٰةَ إِنَّا لَا نُضِيعُ أَجۡرَ ٱلۡمُصۡلِحِينَ ١٧٠","والذين يمسكون بالكتاب وأقاموا الصلاة إنا لا نضيع أجر المصلحين","ފޮތުގައި ހިފަހައްޓައި، ނަމާދު ގާއިމު ކޮށް އުޅުނު މީހުން (ދަންނާށެވެ!) ހަމަކަށަވަރުން، އިސްލާހުކުރާމީހުންގެ ދަރުމަ، ތިމަންރަސްކަލާނގެ ގެއްލެނި ނުކުރައްވާހުށީމެވެ.","",""],["₇ سورة الأعراف","171","۞وَإِذۡ نَتَقۡنَا ٱلۡجَبَلَ فَوۡقَهُمۡ كَأَنَّهُۥ ظُلَّةٞ وَظَنُّوٓاْ أَنَّهُۥ وَاقِعُۢ بِهِمۡ خُذُواْ مَآ ءَاتَيۡنَٰكُم بِقُوَّةٖ وَٱذۡكُرُواْ مَا فِيهِ لَعَلَّكُمۡ تَتَّقُونَ ١٧١","وإذ نتقنا الجبل فوقهم كأنه ظلة وظنوا أنه واقع بهم خذوا ما آتيناكم بقوة واذكروا ما فيه لعلكم تتقون","އަދި ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް ފަރުބަދަ އުފުއްލެވިހިނދު، ހަނދުމަކުރާށެވެ! އެ ފަރުބަދަ އެއުރެންގެ މައްޗަށް އޮތް ހިޔާވައްސެއް ކަހަލައެވެ. އެ ފަރުބަދަ އެއުރެންގެ މައްޗަށް ވެއްޓިދާނެކަމަށް އެއުރެން ހީކުޅައޫއެވެ. (ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވީމެވެ.) ތިމަންރަސްކަލާގެ ތިޔަބައިމީހުންނަށް ދެއްވި ފޮތުގައި، ބާރާއެކު ތިޔަބައިމީހުން ހިފަހައްޓާށެވެ! އަދި އެ ފޮތުގައިވާ ކަންތައް ތިޔަބައިމީހުން ހަނދުމަކުރާށެވެ! (އެއީ) ތިޔަބައިމީހުން ތަގުވާވެރިވުމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","172","وَإِذۡ أَخَذَ رَبُّكَ مِنۢ بَنِيٓ ءَادَمَ مِن ظُهُورِهِمۡ ذُرِّيَّتَهُمۡ وَأَشۡهَدَهُمۡ عَلَىٰٓ أَنفُسِهِمۡ أَلَسۡتُ بِرَبِّكُمۡۖ قَالُواْ بَلَىٰ شَهِدۡنَآۚ أَن تَقُولُواْ يَوۡمَ ٱلۡقِيَٰمَةِ إِنَّا كُنَّا عَنۡ هَٰذَا غَٰفِلِينَ ١٧٢","وإذ أخذ ربك من بني آدم من ظهورهم ذريتهم وأشهدهم على أنفسهم ألست بربكم قالوا بلى شهدنا أن تقولوا يوم القيامة إنا كنا عن هذا غافلين","އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އާދަމުގެދަރިންގެ ކިބައިން އެއުރެންގެ ބުރިކަށިތަކުން އެއުރެންގެ ދަރިފަސްކޮޅު ނެރުއްވައި އެއުރެންގެ އަމިއްލަ ނަފްސުތަކުގެ މައްޗަށް އެއުރެން ހެކިކުރެއްވިހިނދު ހަނދުމަކުރާށެވެ! (އެކަލާނގެ ވަހީކުރެއްވިއެވެ.) ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ކަމުގައި، ތިމަންރަސްކަލާނގެ ވޮޑިގެން ނުވަންހެއްޔެވެ؟ އެއުރެން ދެންނެވޫއެވެ. ނޫނެކެވެ. (އިބަރަސްކަލާނގެއީ، އަޅަމެންގެ ވެރިރަސްކަލާނގެއެވެ.) އެކަމަށް އަޅަމެން ހެކިވެއްޖައީމުއެވެ. (އެކަން އެހެންވީ) މިކަމާމެދު ޣާފިލު ވެގެންވާ ބަޔަކު ކަމުގައި ހަމަކަށަވަރުން، ތިމަންމެންވީމުއޭ، ގިޔާމަތް ދުވަހުން ތިޔަބައިމީހުން ބުނާނެކަމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","173","أَوۡ تَقُولُوٓاْ إِنَّمَآ أَشۡرَكَ ءَابَآؤُنَا مِن قَبۡلُ وَكُنَّا ذُرِّيَّةٗ مِّنۢ بَعۡدِهِمۡۖ أَفَتُهۡلِكُنَا بِمَا فَعَلَ ٱلۡمُبۡطِلُونَ ١٧٣","أو تقولوا إنما أشرك آباؤنا من قبل وكنا ذرية من بعدهم أفتهلكنا بما فعل المبطلون","ނުވަތަ ތިޔަބައިމީހުން ބުނާނެކަމަށްޓަކައެވެ. ޝަރީކު ކޮށްއުޅުނުކަން ކަށަވަރީ، މީގެކުރިން ތިމަންމެންގެ ކާބަފައިންނެވެ. ތިމަންމެންވީ، އެއުރެންގެ ފަހުން އައި ދަރިފަސްކޮޅެއްކަމުގައެވެ. ފަހެ، ބާތިލު ގޮތަށް އުޅުނުމީހުން ކުޅަކަންތަކަށްޓަކައި، ތިމަންމެން ހަލާކުކުރައްވަނީތޯއެވެ؟","",""],["₇ سورة الأعراف","174","وَكَذَٰلِكَ نُفَصِّلُ ٱلۡأٓيَٰتِ وَلَعَلَّهُمۡ يَرۡجِعُونَ ١٧٤","وكذلك نفصل الآيات ولعلهم يرجعون","ތިމަންރަސްކަލާނގެ އާޔަތްތައް ބަޔާންކޮށްދެއްވަނީ، އެފަދައިންނެވެ. އަދި އެއުރެން (ހައްގުގެ މަގަށް) އެނބުރި އައުމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","175","وَٱتۡلُ عَلَيۡهِمۡ نَبَأَ ٱلَّذِيٓ ءَاتَيۡنَٰهُ ءَايَٰتِنَا فَٱنسَلَخَ مِنۡهَا فَأَتۡبَعَهُ ٱلشَّيۡطَٰنُ فَكَانَ مِنَ ٱلۡغَاوِينَ ١٧٥","واتل عليهم نبأ الذي آتيناه آياتنا فانسلخ منها فأتبعه الشيطان فكان من الغاوين","ތިމަންރަސްކަލާނގެ އާޔަތްތައް އެމީހާއަށް ލިބިދެއްވުމުން، އެއިން ވަކިވެގަތް މީހާގެ ޚަބަރު ކަލޭގެފާނު އެއުރެންނަށް ކިޔައިދެއްވާށެވެ! ދެން ޝައިތާނާ އޭނާގެ ފަހަތުން ދިޔައެވެ. ފަހެ، މަގުފުރެދިގެންވާ މީހުންގެ ތެރެއިން އޭނާ ވިއެވެ.","",""],["₇ سورة الأعراف","176","وَلَوۡ شِئۡنَا لَرَفَعۡنَٰهُ بِهَا وَلَٰكِنَّهُۥٓ أَخۡلَدَ إِلَى ٱلۡأَرۡضِ وَٱتَّبَعَ هَوَىٰهُۚ فَمَثَلُهُۥ كَمَثَلِ ٱلۡكَلۡبِ إِن تَحۡمِلۡ عَلَيۡهِ يَلۡهَثۡ أَوۡ تَتۡرُكۡهُ يَلۡهَثۚ ذَّـٰلِكَ مَثَلُ ٱلۡقَوۡمِ ٱلَّذِينَ كَذَّبُواْ بِـَٔايَٰتِنَاۚ فَٱقۡصُصِ ٱلۡقَصَصَ لَعَلَّهُمۡ يَتَفَكَّرُونَ ١٧٦","ولو شئنا لرفعناه بها ولكنه أخلد إلى الأرض واتبع هواه فمثله كمثل الكلب إن تحمل عليه يلهث أو تتركه يلهث ذلك مثل القوم الذين كذبوا بآياتنا فاقصص القصص لعلهم يتفكرون","ތިމަންރަސްކަލާނގެ އިރާދަކުރެއްވިނަމަ، އެ އާޔަތްތަކުގެ ސަބަބުން އޭނާ މަތިވެރި ކުރެއްވީމުހެވެ. އެހެނެއްކަމަކު، އޭނާ ބިމަށް ލެނބިގަތެވެ. އަދި އޭނާގެ އަމިއްލަ އެދުމަށް ތަބާ ވިއެވެ. ފަހެ، އޭނާގެ މިސާލު، ކުއްތާގެ މިސާލު ފަދައެވެ. އެއަށް ހަމަލާ ދިނަސް، ދޫނެރެގެން އޮވެ މާނޭވާލައެވެ. ނުވަތަ އޭތިދޫކޮށްލިޔަސް، ދޫނެރެގެން އޮވެ މާނޭވާލައެވެ. ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުޅަމީހުންގެ މިސާލަކީ އެއީއެވެ. ފަހެ، ކަލޭގެފާނު ވާހަކަތައް ކިޔައިދެއްވާށެވެ! (އެއީ) އެއުރެން ފިކުރުކުރުމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","177","سَآءَ مَثَلًا ٱلۡقَوۡمُ ٱلَّذِينَ كَذَّبُواْ بِـَٔايَٰتِنَا وَأَنفُسَهُمۡ كَانُواْ يَظۡلِمُونَ ١٧٧","ساء مثلا القوم الذين كذبوا بآياتنا وأنفسهم كانوا يظلمون","ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކޮށް، އަދި ހަމަ އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް އަނިޔާވެރިވެ އުޅުނުމީހުން، މިސާލެއްގެ ގޮތުން ނުބައިކަމާއެވެ!","",""],["₇ سورة الأعراف","178","مَن يَهۡدِ ٱللَّهُ فَهُوَ ٱلۡمُهۡتَدِيۖ وَمَن يُضۡلِلۡ فَأُوْلَـٰٓئِكَ هُمُ ٱلۡخَٰسِرُونَ ١٧٨","من يهد الله فهو المهتدي ومن يضلل فأولئك هم الخاسرون","ﷲ ތެދުމަގު ދެއްކެވި މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކީ ތެދުމަގު ލިބިގެންވާ މީހެކެވެ. އަދި އެކަލާނގެ މަގުފުރައްދަވާމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ، ހަމަ ގެއްލެނިވެގެންވާ މީހުންނެވެ.","",""],["₇ سورة الأعراف","179","وَلَقَدۡ ذَرَأۡنَا لِجَهَنَّمَ كَثِيرٗا مِّنَ ٱلۡجِنِّ وَٱلۡإِنسِۖ لَهُمۡ قُلُوبٞ لَّا يَفۡقَهُونَ بِهَا وَلَهُمۡ أَعۡيُنٞ لَّا يُبۡصِرُونَ بِهَا وَلَهُمۡ ءَاذَانٞ لَّا يَسۡمَعُونَ بِهَآۚ أُوْلَـٰٓئِكَ كَٱلۡأَنۡعَٰمِ بَلۡ هُمۡ أَضَلُّۚ أُوْلَـٰٓئِكَ هُمُ ٱلۡغَٰفِلُونَ ١٧٩","ولقد ذرأنا لجهنم كثيرا من الجن والإنس لهم قلوب لا يفقهون بها ولهم أعين لا يبصرون بها ولهم آذان لا يسمعون بها أولئك كالأنعام بل هم أضل أولئك هم الغافلون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ޖިންނީންނާއި، އިންސީންގެ ތެރެއިން ގިނަބަޔަކު ނަރަކަޔަށްޓަކައި ހެއްދެވީމެވެ. އެ ހިތްތަކުން (ހައްގު ގޮތް) ނުވިސްނޭ ހިތްތަކެއް އެއުރެންނަށްވެއެވެ. އަދި އެ ލޯތަކުން (ހައްގު މަގު) ނުދެކޭ ލޯތަކެއް އެއުރެންނަށްވެއެވެ. އަދި އެ ކަންފަތްތަކުން (ހައްގު އަޑު) ނާހާ ކަންފަތްތަކެއްވެސް، އެއުރެންނަށްވެއެވެ. އެއުރެން ގެރިބަކަރި ޖަމަލު ފަދައެވެ. އަދި ކިއެއްތަ! އެތަކެއްޗަށް ވުރެވެސް އެއުރެން މަގުފުރެދުންބޮޑެވެ. އެއުރެންނަކީ ހަމަ ޣާފިލު ވެގެންވާ ބަޔެކެވެ.","",""],["₇ سورة الأعراف","180","وَلِلَّهِ ٱلۡأَسۡمَآءُ ٱلۡحُسۡنَىٰ فَٱدۡعُوهُ بِهَاۖ وَذَرُواْ ٱلَّذِينَ يُلۡحِدُونَ فِيٓ أَسۡمَـٰٓئِهِۦۚ سَيُجۡزَوۡنَ مَا كَانُواْ يَعۡمَلُونَ ١٨٠","ولله الأسماء الحسنى فادعوه بها وذروا الذين يلحدون في أسمائه سيجزون ما كانوا يعملون","އެންމެރިވެތި ނަންފުޅުތައް މަލަކަ ވެގެންވަނީ، ﷲއަށެވެ. ފަހެ، އެ ނަންފުޅުތަކުން ތިޔަބައިމީހުން އެކަލާނގެ ހަޒުރަތަށް ދުއާކުރާށެވެ! އަދި އެކަލާނގެ ނަންފުޅުތަކާމެދު، ހައްގު މަގުން އެއްކިބާވެ އުޅޭމީހުން، ތިޔަބައިމީހުން ދޫކޮށްލާށެވެ! އެއުރެން ކޮށްއުޅުނު ކަންތަކަށް އެއުރެންނަށް ޖަޒާ ދެއްވާހުށްޓެވެ.","",""],["₇ سورة الأعراف","181","وَمِمَّنۡ خَلَقۡنَآ أُمَّةٞ يَهۡدُونَ بِٱلۡحَقِّ وَبِهِۦ يَعۡدِلُونَ ١٨١","وممن خلقنا أمة يهدون بالحق وبه يعدلون","ހައްގު ގޮތުގެމަތިން މަގުދައްކައި، އަދި އެގޮތުގެމަތީން ޢަދުލުވެރިވެއުޅޭ ބަޔަކު، ތިމަންރަސްކަލާނގެ ހެއްދެވި މީހުންގެ ތެރެއިންވެއެވެ.","",""],["₇ سورة الأعراف","182","وَٱلَّذِينَ كَذَّبُواْ بِـَٔايَٰتِنَا سَنَسۡتَدۡرِجُهُم مِّنۡ حَيۡثُ لَا يَعۡلَمُونَ ١٨٢","والذين كذبوا بآياتنا سنستدرجهم من حيث لا يعلمون","ތިމަންރަސްލާނގެ އާޔަތްތައް ދޮގުކުޅަމީހުން، އެއުރެންނަށް ނޭނގޭނޭގޮތުން (އަޒާބުގެ ތެރެއަށް) ތިމަންރަސްކަލާނގެ އެއުރެން ގެންދަވާހުށީމެވެ.","",""],["₇ سورة الأعراف","183","وَأُمۡلِي لَهُمۡۚ إِنَّ كَيۡدِي مَتِينٌ ١٨٣","وأملي لهم إن كيدي متين","އަދި އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ލަސްކުރައްވަމެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ރޭއްވެވުން ގަދަފަދަވެގެންވެއެވެ.","",""],["₇ سورة الأعراف","184","أَوَلَمۡ يَتَفَكَّرُواْۗ مَا بِصَاحِبِهِم مِّن جِنَّةٍۚ إِنۡ هُوَ إِلَّا نَذِيرٞ مُّبِينٌ ١٨٤","أولم يتفكروا ما بصاحبهم من جنة إن هو إلا نذير مبين","އަދި އެއުރެން ފިކުރުވެސް ނުކުރަނީހެއްޔެވެ؟ އެއުރެންގެ އެކުވެރިޔާގެ ކިބައިގައި (އެބަހީ: މުޙައްމަދުގެފާނުގެ ކިބައިގައި) އެއްވެސް މޮޔަކަމެއްނެތެވެ. ބަޔާންވެގެން ހުންނެވި އިންޒާރުކުރައްވާ ބޭކަލަކު ކަމުގައި މެނުވީ، އެކަލޭގެފާނު ނުވެތެވެ.","",""],["₇ سورة الأعراف","185","أَوَلَمۡ يَنظُرُواْ فِي مَلَكُوتِ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ وَمَا خَلَقَ ٱللَّهُ مِن شَيۡءٖ وَأَنۡ عَسَىٰٓ أَن يَكُونَ قَدِ ٱقۡتَرَبَ أَجَلُهُمۡۖ فَبِأَيِّ حَدِيثِۭ بَعۡدَهُۥ يُؤۡمِنُونَ ١٨٥","أولم ينظروا في ملكوت السماوات والأرض وما خلق الله من شيء وأن عسى أن يكون قد اقترب أجلهم فبأي حديث بعده يؤمنون","އަދި އުޑުތަކާއި ބިމުގެ ވެރިކަމާމެދުގައްޔާއި، ﷲ ހައްދަވާފައިވާ އެންމެހާ ތަކެއްޗާ މެދުގައްޔާއި، އެއުރެންގެ އަޖަލު ގާތްވެއްޖެކަމާ މެދުގައި، އެއުރެން ވިސްނައި ނުބަލަނީހެއްޔެވެ؟ އެއަށްފަހު، އެއުރެން އީމާން ވަނީ ފަހެ، ކޮންވާހަކައަކަށް ހެއްޔެވެ؟","",""],["₇ سورة الأعراف","186","مَن يُضۡلِلِ ٱللَّهُ فَلَا هَادِيَ لَهُۥۚ وَيَذَرُهُمۡ فِي طُغۡيَٰنِهِمۡ يَعۡمَهُونَ ١٨٦","من يضلل الله فلا هادي له ويذرهم في طغيانهم يعمهون","ﷲ މަގުފުރައްދަވާމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް ތެދުމަގުދައްކާނޭ ފަރާތެއް ނުވެތެވެ. އަދި ދެވޭ ނުދެވޭ ތަނެއްނޭނގި ތިބޭ ޙާލުގައި، ފުރެދުމުގެ ތެރެޔަށް އެކަލާނގެ އެއުރެން ދޫކުރައްވަތެވެ.","",""],["₇ سورة الأعراف","187","يَسۡـَٔلُونَكَ عَنِ ٱلسَّاعَةِ أَيَّانَ مُرۡسَىٰهَاۖ قُلۡ إِنَّمَا عِلۡمُهَا عِندَ رَبِّيۖ لَا يُجَلِّيهَا لِوَقۡتِهَآ إِلَّا هُوَۚ ثَقُلَتۡ فِي ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِۚ لَا تَأۡتِيكُمۡ إِلَّا بَغۡتَةٗۗ يَسۡـَٔلُونَكَ كَأَنَّكَ حَفِيٌّ عَنۡهَاۖ قُلۡ إِنَّمَا عِلۡمُهَا عِندَ ٱللَّهِ وَلَٰكِنَّ أَكۡثَرَ ٱلنَّاسِ لَا يَعۡلَمُونَ ١٨٧","يسألونك عن الساعة أيان مرساها قل إنما علمها عند ربي لا يجليها لوقتها إلا هو ثقلت في السماوات والأرض لا تأتيكم إلا بغتة يسألونك كأنك حفي عنها قل إنما علمها عند الله ولكن أكثر الناس لا يعلمون","ގިޔާމަތްގެ ވަގުތާމެދު، އެއުރެން ކަލޭގެފާނާ ސުވާލުކުރެތެވެ. އެދުވަސް ލައިގަންނާނީ ކޮން އިރަކުންތޯއެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަން ދެނެވޮޑިގަތުންވަނީ، ހަމައެކަނި ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތު ގައެވެ. އެކަލާނގެ މެނުވީ، އެކަމުގެ ވަގުތަށް އެކަން ފާޅުނުކުރައްވާ ހުށްޓެވެ. އުޑުތަކާއި، ބިމުގައި އެކަން ބުރަކަމަކަށް ވެފައިވެއެވެ. ކުއްލިއަކަށްމެނުވީ، އެކަން ތިޔަބައިމީހުންނާ ހަމަޔަކަށް ނާންނަހުށްޓެވެ. (އެކަމާމެދު) ކަލޭގެފާނާ އެއުރެން ސުވާލުކުރާއިރު، އެކަމުގެ ހުރިހާ ޚަބަރެއް، ކަލޭގެފާނު ދެނެވަޑައިގަންނަވާ ކަހަލައެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަން ދެނެވޮޑިގަތުންވަނީ، ހަމައެކަނި ﷲގެ ހަޒުރަތު ގައެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުންނަކަށް (އެކަމެއް) ނޭނގެތެވެ.","",""],["₇ سورة الأعراف","188","قُل لَّآ أَمۡلِكُ لِنَفۡسِي نَفۡعٗا وَلَا ضَرًّا إِلَّا مَا شَآءَ ٱللَّهُۚ وَلَوۡ كُنتُ أَعۡلَمُ ٱلۡغَيۡبَ لَٱسۡتَكۡثَرۡتُ مِنَ ٱلۡخَيۡرِ وَمَا مَسَّنِيَ ٱلسُّوٓءُۚ إِنۡ أَنَا۠ إِلَّا نَذِيرٞ وَبَشِيرٞ لِّقَوۡمٖ يُؤۡمِنُونَ ١٨٨","قل لا أملك لنفسي نفعا ولا ضرا إلا ما شاء الله ولو كنت أعلم الغيب لاستكثرت من الخير وما مسني السوء إن أنا إلا نذير وبشير لقوم يؤمنون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲ އިރާދަކުރެއްވި ކަމެއްމެނުވީ ތިމަންކަލޭގެފާނުގެ އަމިއްލަ ނަފްސަށް މަންފާއެއް، ނުވަތަ ގެއްލުމެއް ލިބިގަތުމުގެ ބާރު، ތިމަންކަލޭގެފާނަށް މަލަކަ ވެގެނެއް ނުވެތެވެ. އަދި ތިމަންކަލޭގެފާނަށް ޣައިބު އެނގިވަޑައިގަންނަވާ ކަމުގައި ވީނަމަ، ތިމަންކަލޭގެފާނު ހެޔޮކަންތައް ގިނަކުރެއްވީމުހެވެ. އަދި ނުބައިކަމެއް ތިމަންކަލޭގެފާނުންގައި ނުބީހުނީހެވެ. ބިރުވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު ކަމުގައްޔާއި، އީމާންވާ ބަޔަކަށް އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު ކަމުގައި މެނުވީ، ތިމަންކަލޭގެފާނު ނުވަމެވެ.","",""],["₇ سورة الأعراف","189","۞هُوَ ٱلَّذِي خَلَقَكُم مِّن نَّفۡسٖ وَٰحِدَةٖ وَجَعَلَ مِنۡهَا زَوۡجَهَا لِيَسۡكُنَ إِلَيۡهَاۖ فَلَمَّا تَغَشَّىٰهَا حَمَلَتۡ حَمۡلًا خَفِيفٗا فَمَرَّتۡ بِهِۦۖ فَلَمَّآ أَثۡقَلَت دَّعَوَا ٱللَّهَ رَبَّهُمَا لَئِنۡ ءَاتَيۡتَنَا صَٰلِحٗا لَّنَكُونَنَّ مِنَ ٱلشَّـٰكِرِينَ ١٨٩","هو الذي خلقكم من نفس واحدة وجعل منها زوجها ليسكن إليها فلما تغشاها حملت حملا خفيفا فمرت به فلما أثقلت دعوا الله ربهما لئن آتيتنا صالحا لنكونن من الشاكرين","އެކަލާނގެއީ، އެންމެ ނަފްސަކުން ތިޔަބައިމީހުން ހެއްދެވި ކަލާނގެއެވެ. އަދި އެ ނަފްސުން، އެ ނަފްސުގެ އަނބި ހެއްދެވިއެވެ. (އެއީ) އެކަނބުލޭގެ ގާތަށްގޮސް، ހިތްހަމަޖެހުމާއި ހަމަހިމޭންކަން ލިބިގަތުމަށެވެ. ފަހެ، އޭނާ އެކަނބުލޭގެއާ އެއްދާންކުރި ހިނދު، ލުއިގޮތެއްގައި ހައްޔަރުގައި އިނދެ އެކަމުގައި ދުވަސްތަކެއް ވޭތުވިއެވެ. ދެންފަހެ، (އެކަމުން) ބުރަވިހިނދު، އެ ދެމީހުންގެ ވެރި ﷲއަށް އެ ދެމީހުން ދުއާކުރިއެވެ. އިބަރަސްކަލާނގެ އަޅަމެންނަށް ސާލިހު ދަރިއަކު ދެއްވައިފިނަމަ، ޝުކުރުކުރާ މީހުންގެ ތެރެއިން ހަމަކަށަވަރުން، އަޅަމެން ވާހުށީމެވެ.","",""],["₇ سورة الأعراف","190","فَلَمَّآ ءَاتَىٰهُمَا صَٰلِحٗا جَعَلَا لَهُۥ شُرَكَآءَ فِيمَآ ءَاتَىٰهُمَاۚ فَتَعَٰلَى ٱللَّهُ عَمَّا يُشۡرِكُونَ ١٩٠","فلما آتاهما صالحا جعلا له شركاء فيما آتاهما فتعالى الله عما يشركون","ފަހެ، އެ ދެމީހުންނަށް ސާލިހު ދަރިއަކު ދެއްވިހިނދު، އެކަލާނގެ އެ ދެމީހުންނަށް ދެއްވި ދެއްވުމާމެދު، އެ ދެމީހުން (އެބަހީ: އާދަމުގެފާނުގެ ދަރިކޮޅުގެ މީހުންކުރެ ކާފިރު ވިމީހުން) އެކަލާނގެއަށް ޝަރީކުންތަކެއް ލައިފިއެވެ. ފަހެ، އެއުރެން ޝަރީކުކުރާ ތަކެތި ފިޔަވައި، ﷲ މަތިވެރިވެ ވޮޑިގެންވެއެވެ.","",""],["₇ سورة الأعراف","191","أَيُشۡرِكُونَ مَا لَا يَخۡلُقُ شَيۡـٔٗا وَهُمۡ يُخۡلَقُونَ ١٩١","أيشركون ما لا يخلق شيئا وهم يخلقون","އެއްވެސް އެއްޗެއް ހެދުމަށް ކުޅަދާނަވެގެންނުވާ ތަކެތި، އެއުރެން (އެކަލާނގެއަށް) ޝަރީކުކުރަނީހެއްޔެވެ؟ ޚުދު އެތަކެއްޗަކީ، ހައްދަވާފައިވާ ތަކެއްޗެވެ.","",""],["₇ سورة الأعراف","192","وَلَا يَسۡتَطِيعُونَ لَهُمۡ نَصۡرٗا وَلَآ أَنفُسَهُمۡ يَنصُرُونَ ١٩٢","ولا يستطيعون لهم نصرا ولا أنفسهم ينصرون","އަދި އެއުރެންނަށް އެއްވެސް ނަސްރެއް ދިނުމަކަށް އެތަކެއްޗަކަށް ކުޅަދާނަވެގެނެއް ނުވެތެވެ. އަދި އެތަކެތީގެ އަމިއްލަ ޒާތަށްވެސް، ނަސްރެއް ނުދެވޭނޭމެއެވެ.","",""],["₇ سورة الأعراف","193","وَإِن تَدۡعُوهُمۡ إِلَى ٱلۡهُدَىٰ لَا يَتَّبِعُوكُمۡۚ سَوَآءٌ عَلَيۡكُمۡ أَدَعَوۡتُمُوهُمۡ أَمۡ أَنتُمۡ صَٰمِتُونَ ١٩٣","وإن تدعوهم إلى الهدى لا يتبعوكم سواء عليكم أدعوتموهم أم أنتم صامتون","ތިޔަބައިމީހުން އެތަކެއްޗަށް ތެދުމަގަށް ގޮވިޔަސް، އެތަކެއްޗެއް ތިޔަބައިމީހުންނަކަށް ތަބައެއް ނުވާނެތެވެ. އެ ތަކެއްޗަށް ތިޔަބައިމީހުން ގޮވިޔަސް، ނުވަތަ ނުގޮވައި ހަނުތިއްބަސް، ތިޔަބައިމީހުންނަށް ހަމަހަމަވެގެންވެތެވެ.","",""],["₇ سورة الأعراف","194","إِنَّ ٱلَّذِينَ تَدۡعُونَ مِن دُونِ ٱللَّهِ عِبَادٌ أَمۡثَالُكُمۡۖ فَٱدۡعُوهُمۡ فَلۡيَسۡتَجِيبُواْ لَكُمۡ إِن كُنتُمۡ صَٰدِقِينَ ١٩٤","إن الذين تدعون من دون الله عباد أمثالكم فادعوهم فليستجيبوا لكم إن كنتم صادقين","ހަމަކަށަވަރުން، ﷲ ފިޔަވައި ތިޔަބައިމީހުން ދުއާ ކޮށް އަޅުކަން ކޮށްއުޅޭ ފަރާތްތަކަކީ، ތިޔަބައިމީހުންނާ އެއްފަދަ އަޅުންތަކެކެވެ. ފަހެ، ތިޔަބައިމީހުންނީ ތެދުބުނާ މީހުން ކަމުގައިވާނަމަ، ތިޔަބައިމީހުންނަށް އެފަރާތްތައް އިޖާބަދޭތޯ ނިކަން ތިޔަބައިމީހުން އެފަރާތްތަކަށް ގޮވައިބަލާށެވެ!","",""],["₇ سورة الأعراف","195","أَلَهُمۡ أَرۡجُلٞ يَمۡشُونَ بِهَآۖ أَمۡ لَهُمۡ أَيۡدٖ يَبۡطِشُونَ بِهَآۖ أَمۡ لَهُمۡ أَعۡيُنٞ يُبۡصِرُونَ بِهَآۖ أَمۡ لَهُمۡ ءَاذَانٞ يَسۡمَعُونَ بِهَاۗ قُلِ ٱدۡعُواْ شُرَكَآءَكُمۡ ثُمَّ كِيدُونِ فَلَا تُنظِرُونِ ١٩٥","ألهم أرجل يمشون بها أم لهم أيد يبطشون بها أم لهم أعين يبصرون بها أم لهم آذان يسمعون بها قل ادعوا شركاءكم ثم كيدون فلا تنظرون","އެއިން ހިނގާނޭ ފައިތަކެއް އެފަރާތްތަކަށް ވޭހެއްޔެވެ؟ ނުވަތަ އެއިން ބާރުދައްކައި އުޅޭނޭ އަތްތަކެއް އެފަރާތްތަކަށް ވޭހެއްޔެވެ؟ ނުވަތަ އެއިން ދެކޭނޭ ލޯތަކެއް އެފަރާތްތަކަށް ވޭހެއްޔެވެ؟ ނުވަތަ އެއިން އަހާނޭ ކަންފަތްތަކެއް އެފަރާތްތަކަށް ވޭހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންގެ ބައިވެރިންތަކަށް ތިޔަބައިމީހުން ނިކަން ގޮވައިބަލާށެވެ! ދެން ތިމަންކަލޭގެފާނާމެދު މަކަރުވެރި ރޭވުން ރާވަމުން ގެންގޮސްބަލާށެވެ! އަދި ތިމަންކަލޭގެފާނަށްޓަކައި ލަސްނުކުރާށެވެ!","",""],["₇ سورة الأعراف","196","إِنَّ وَلِـِّۧيَ ٱللَّهُ ٱلَّذِي نَزَّلَ ٱلۡكِتَٰبَۖ وَهُوَ يَتَوَلَّى ٱلصَّـٰلِحِينَ ١٩٦","إن وليي الله الذي نزل الكتاب وهو يتولى الصالحين","ހަމަކަށަވަރުން، ތިމަންގެ އެހީތެރި ފަރާތަކީ، ﷲއެވެ. އެކަލާނގެއީ، ފޮތް ބާވައިލެއްވި ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެއީ، ސާލިހުންނަށް އެހީތެރިވެ ވޮޑިގަންނަވާ ރަސްކަލާނގެއެވެ.","",""],["₇ سورة الأعراف","197","وَٱلَّذِينَ تَدۡعُونَ مِن دُونِهِۦ لَا يَسۡتَطِيعُونَ نَصۡرَكُمۡ وَلَآ أَنفُسَهُمۡ يَنصُرُونَ ١٩٧","والذين تدعون من دونه لا يستطيعون نصركم ولا أنفسهم ينصرون","އަދި އެކަލާނގެ ފިޔަވައި ތިޔަބައިމީހުން އަޅުކަންކޮށް އުޅޭ ފަރާތްތަކަށް، ތިޔަބައިމީހުންނަށް ނަސްރު ދިނުމަކަށް ކުޅަދާނަވެގެނެއް ނުވެތެވެ. އަދި އެފަރާތްތަކުގެ އަމިއްލަ ނަފްސު ތަކަށްވެސް ނަސްރެއް ނުދެވޭނެތެވެ.","",""],["₇ سورة الأعراف","198","وَإِن تَدۡعُوهُمۡ إِلَى ٱلۡهُدَىٰ لَا يَسۡمَعُواْۖ وَتَرَىٰهُمۡ يَنظُرُونَ إِلَيۡكَ وَهُمۡ لَا يُبۡصِرُونَ ١٩٨","وإن تدعوهم إلى الهدى لا يسمعوا وتراهم ينظرون إليك وهم لا يبصرون","ތިޔަބައިމީހުން އެތަކެއްޗަށް ތެދުމަގަށް ގޮވިޔަސް، އެފަރާތްތަކަކަށް ނީވެތެވެ. އަދި އެފަރާތްތައް ކަލޭގެފާނަށް ބަލާތީ ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނެތެވެ. ނަމަވެސް (ހަގީގަތުގައި) އެފަރާތްތަކަކަށް (ކަލޭގެފާނެއް) ނުފެނެތެވެ.","",""],["₇ سورة الأعراف","199","خُذِ ٱلۡعَفۡوَ وَأۡمُرۡ بِٱلۡعُرۡفِ وَأَعۡرِضۡ عَنِ ٱلۡجَٰهِلِينَ ١٩٩","خذ العفو وأمر بالعرف وأعرض عن الجاهلين","ކަލޭގެފާނު އަފޫކުރެއްވުމުގައި ހިއްޕަވާށެވެ! އަދި ހެޔޮކަންތަކަށް އަމުރުކުރައްވާށެވެ! އަދި ޖާހިލުންނާ އެއްކިބާވެ ވަޑައިގަންނަވާށެވެ!","",""],["₇ سورة الأعراف","200","وَإِمَّا يَنزَغَنَّكَ مِنَ ٱلشَّيۡطَٰنِ نَزۡغٞ فَٱسۡتَعِذۡ بِٱللَّهِۚ إِنَّهُۥ سَمِيعٌ عَلِيمٌ ٢٠٠","وإما ينزغنك من الشيطان نزغ فاستعذ بالله إنه سميع عليم","އަދި ހަމަކަށަވަރުން، ޝައިތާނާގެ ފަރާތުން ވަސްވާސްތެރިކަމެއް އައިސް ކަލޭގެފާނުގެ ހިތްޕުޅަށް ވަންނަނަމަ، ﷲގެ ރައްކާތެރިކަމަށް އެދިވަޑައިގަންނަވާށެވެ! ހަމަކަށަވަރުން، އެކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ މޮޅަށް ދެނެވޮޑިގަންނަވާ ރަސްކަލާނގެއެވެ.","",""],["₇ سورة الأعراف","201","إِنَّ ٱلَّذِينَ ٱتَّقَوۡاْ إِذَا مَسَّهُمۡ طَـٰٓئِفٞ مِّنَ ٱلشَّيۡطَٰنِ تَذَكَّرُواْ فَإِذَا هُم مُّبۡصِرُونَ ٢٠١","إن الذين اتقوا إذا مسهم طائف من الشيطان تذكروا فإذا هم مبصرون","ހަމަކަށަވަރުން، ތަގުވާވެރިވި މީހުންގައި ޝައިތާނާގެ ފަރާތުން އަންނަ އައުމެއް ބީހިއްޖެނަމަ، އެއުރެން (ﷲ) ހަނދުމަކުރެތެވެ. ފަހެ، އެހިނދު ލޯހުޅުވިފައިވާ ބަޔަކު ކަމުގައި އެއުރެންވެއެވެ.","",""],["₇ سورة الأعراف","202","وَإِخۡوَٰنُهُمۡ يَمُدُّونَهُمۡ فِي ٱلۡغَيِّ ثُمَّ لَا يُقۡصِرُونَ ٢٠٢","وإخوانهم يمدونهم في الغي ثم لا يقصرون","އަދި އެ ޝައިތާނުންގެ އަޚުން، އެއުރެން މަގު ފުރެއްދުމުގެ ތެރޭގައި ދަމަހައްޓައެވެ. ދެން އެކަންތަކުގައި އެއުރެން ދުލެއް ނުކުރެތެވެ.","",""],["₇ سورة الأعراف","203","وَإِذَا لَمۡ تَأۡتِهِم بِـَٔايَةٖ قَالُواْ لَوۡلَا ٱجۡتَبَيۡتَهَاۚ قُلۡ إِنَّمَآ أَتَّبِعُ مَا يُوحَىٰٓ إِلَيَّ مِن رَّبِّيۚ هَٰذَا بَصَآئِرُ مِن رَّبِّكُمۡ وَهُدٗى وَرَحۡمَةٞ لِّقَوۡمٖ يُؤۡمِنُونَ ٢٠٣","وإذا لم تأتهم بآية قالوا لولا اجتبيتها قل إنما أتبع ما يوحى إلي من ربي هذا بصائر من ربكم وهدى ورحمة لقوم يؤمنون","އަދި ކަލޭގެފާނު އެއުރެންނާ ހަމައަށް އާޔަތެއް ނުގެންނަވައިފިނަމަ، އެއުރެން ދަންނަވާނެތެވެ. ކަލޭގެފާނު (އަމިއްލަފުޅަށް) އެކަން އިޚްތިޔާރު ނުކުރެއްވީ ކީއްވެގެންތޯއެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނު ތަބާ ވާކަން ކަށަވަރީ، ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ތިމަންކަލޭގެފާނަށް އިއްވަވާ ވަހީއަށެވެ. މިއީ (އެބަހީ: މި ގުރްއާނަކީ) ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައި ހެކިތަކެކެވެ. އަދި އީމާންވާ ބަޔަކަށް ތެދުމަގެކެވެ. އަދި ރަހުމަތެއްމެއެވެ.","",""],["₇ سورة الأعراف","204","وَإِذَا قُرِئَ ٱلۡقُرۡءَانُ فَٱسۡتَمِعُواْ لَهُۥ وَأَنصِتُواْ لَعَلَّكُمۡ تُرۡحَمُونَ ٢٠٤","وإذا قرئ القرآن فاستمعوا له وأنصتوا لعلكم ترحمون","އަދި ގުރްއާން ކިޔަވާހިނދު ތިޔަބައިމީހުން ހަނުތިބެ، އެއަށް ކަނުލައި އަހާށެވެ! (އެއީ) ތިޔަބައިމީހުންނަށް ރަހުމަތް ލެއްވުމަށްޓަކައެވެ.","",""],["₇ سورة الأعراف","205","وَٱذۡكُر رَّبَّكَ فِي نَفۡسِكَ تَضَرُّعٗا وَخِيفَةٗ وَدُونَ ٱلۡجَهۡرِ مِنَ ٱلۡقَوۡلِ بِٱلۡغُدُوِّ وَٱلۡأٓصَالِ وَلَا تَكُن مِّنَ ٱلۡغَٰفِلِينَ ٢٠٥","واذكر ربك في نفسك تضرعا وخيفة ودون الجهر من القول بالغدو والآصال ولا تكن من الغافلين","އަދި ކަލޭގެފާނުގެ ހިތްޕުޅުން ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަނދުމަކުރައްވާށެވެ! މަޑުމޮޅިވެ، ބިރުވެތިވާ ޙާލު ގައެވެ. ބަސްބުނުމުގެ ތެރެއިން އަޑުހަރުކުރުމަށްވުރެ މަޑުންނެވެ. ހެނދުނާއި ހަވީރުގެ ވަގުތު ތަކުގައެވެ. އަދި ޣާފިލު ވެގެންވާ މީހުންގެ ތެރެއިން ކަލޭގެފާނު ވެވަޑައިނުގަންނަވާށެވެ!","",""],["₇ سورة الأعراف","206","إِنَّ ٱلَّذِينَ عِندَ رَبِّكَ لَا يَسۡتَكۡبِرُونَ عَنۡ عِبَادَتِهِۦ وَيُسَبِّحُونَهُۥ وَلَهُۥ يَسۡجُدُونَۤ۩ ٢٠٦","إن الذين عند ربك لا يستكبرون عن عبادته ويسبحونه وله يسجدون","ހަމަކަށަވަރުން ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތު ގައިވާ މަލާއިކަތުން، އެކަލާނގެއަށް އަޅުކަން ކުރެއްވުމަށް ބޮޑާވެއެއް ނުގަނެތެވެ. އަދި އެބޭކަލުން އެކަލާނގެއަށް ތަސްބީހަ ދަންނަވަތެވެ. އަދި އެބޭކަލުން ސަޖިދަކުރައްވަނީ އެކަލާނގެއަށެވެ.","",""],["₈ سورة الأَنفال","1","بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ\n<br><br>\nيَسۡـَٔلُونَكَ عَنِ ٱلۡأَنفَالِۖ قُلِ ٱلۡأَنفَالُ لِلَّهِ وَٱلرَّسُولِۖ فَٱتَّقُواْ ٱللَّهَ وَأَصۡلِحُواْ ذَاتَ بَيۡنِكُمۡۖ وَأَطِيعُواْ ٱللَّهَ وَرَسُولَهُۥٓ إِن كُنتُم مُّؤۡمِنِينَ ١","بسم الله الرحمن الرحيم يسألونك عن الأنفال قل الأنفال لله والرسول فاتقوا الله وأصلحوا ذات بينكم وأطيعوا الله ورسوله إن كنتم مؤمنين","ޣަނީމާ މުދަލާމެދު އެއުރެން ކަލޭގެފާނާ ސުވާލުކުރެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ޣަނީމާ މުދާ ވަނީ، ﷲއަށާއި، ރަސޫލާއަށެވެ. ފަހެ، ﷲއަށް ތިޔަބައިމީހުން ތަގުވާވެރިވާށެވެ! އަދި ތިޔަބައިމީހުންގެ ދެމެދުގެ ގުޅުންތައް އިސްލާހުކުރާށެވެ! އަދި ތިޔަބައިމީހުން މުއުމިނުން ކަމުގައިވާނަމަ، ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް ތިޔަބައިމީހުން ކިޔަމަންވާށެވެ!","",""],["₈ سورة الأَنفال","2","إِنَّمَا ٱلۡمُؤۡمِنُونَ ٱلَّذِينَ إِذَا ذُكِرَ ٱللَّهُ وَجِلَتۡ قُلُوبُهُمۡ وَإِذَا تُلِيَتۡ عَلَيۡهِمۡ ءَايَٰتُهُۥ زَادَتۡهُمۡ إِيمَٰنٗا وَعَلَىٰ رَبِّهِمۡ يَتَوَكَّلُونَ ٢","إنما المؤمنون الذين إذا ذكر الله وجلت قلوبهم وإذا تليت عليهم آياته زادتهم إيمانا وعلى ربهم يتوكلون","މުއުމިނުން ވާކަން ކަށަވަރީ، ﷲ ހަނދުމަކުރާހިނދު އެއުރެންގެ ހިތްތައް ބިރުވެތިވާ މީހުން ކަމުގައެވެ. އަދި އެކަލާނގެ (ބާވައިލެއްވި) އާޔަތްތައް އެއުރެންނަށް ކިޔައިދޭހިނދު، އެއުރެންގެ އީމާން ކަން އިތުރުވާ މީހުން ކަމުގައެވެ. އަދި އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ވަކީލުކުރާ މީހުން ކަމުގައެވެ.","",""],["₈ سورة الأَنفال","3","ٱلَّذِينَ يُقِيمُونَ ٱلصَّلَوٰةَ وَمِمَّا رَزَقۡنَٰهُمۡ يُنفِقُونَ ٣","الذين يقيمون الصلاة ومما رزقناهم ينفقون","އެއުރެންނީ، ނަމާދު ގާއިމުކުރާ މީހުންނެވެ. އަދި އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ދެއްވި ތަކެތިން ހޭދަކުރާ މީހުންނެވެ.","",""],["₈ سورة الأَنفال","4","أُوْلَـٰٓئِكَ هُمُ ٱلۡمُؤۡمِنُونَ حَقّٗاۚ لَّهُمۡ دَرَجَٰتٌ عِندَ رَبِّهِمۡ وَمَغۡفِرَةٞ وَرِزۡقٞ كَرِيمٞ ٤","أولئك هم المؤمنون حقا لهم درجات عند ربهم ومغفرة ورزق كريم","ހަގީގަތުގައި މުއުމިނުންނަކީ، ހަމަ އެއުރެންނެވެ. އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި މަތިވެރި ދަރަޖަތަކާއި، ފާފަފުއްސެވުމާއި، ދީލަތިވެގެންވާ ރިޒްގެއުރެންނަށް ހުށްޓެވެ.","",""],["₈ سورة الأَنفال","5","كَمَآ أَخۡرَجَكَ رَبُّكَ مِنۢ بَيۡتِكَ بِٱلۡحَقِّ وَإِنَّ فَرِيقٗا مِّنَ ٱلۡمُؤۡمِنِينَ لَكَٰرِهُونَ ٥","كما أخرجك ربك من بيتك بالحق وإن فريقا من المؤمنين لكارهون","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، ހައްގު ގޮތުގައި ކަލޭގެފާނުގެ ގެކޮޅުން ކަލޭގެފާނު ނެރުއްވި ފަދައިންނެވެ. ހަމަކަށަވަރުން، މުއުމިނުންގެ ބަޔަކު (އެކަމާ) ނުރުހުންވެގެންވާކަން ކަށަވަރެވެ.","",""],["₈ سورة الأَنفال","6","يُجَٰدِلُونَكَ فِي ٱلۡحَقِّ بَعۡدَ مَا تَبَيَّنَ كَأَنَّمَا يُسَاقُونَ إِلَى ٱلۡمَوۡتِ وَهُمۡ يَنظُرُونَ ٦","يجادلونك في الحق بعد ما تبين كأنما يساقون إلى الموت وهم ينظرون","ހައްގު ބަޔާން ވުމަށްފަހު، އެ ހައްގާމެދު އެއުރެން ކަލޭގެފާނާ ޖަދަލުކުރެތެވެ. އެއުރެން ބަލަބަލާތިއްބައި މަރަށް ގެންދެވޭ ބަޔަކު ކަމުގައި އެއުރެންވާ ކަހަލައެވެ.","",""],["₈ سورة الأَنفال","7","وَإِذۡ يَعِدُكُمُ ٱللَّهُ إِحۡدَى ٱلطَّآئِفَتَيۡنِ أَنَّهَا لَكُمۡ وَتَوَدُّونَ أَنَّ غَيۡرَ ذَاتِ ٱلشَّوۡكَةِ تَكُونُ لَكُمۡ وَيُرِيدُ ٱللَّهُ أَن يُحِقَّ ٱلۡحَقَّ بِكَلِمَٰتِهِۦ وَيَقۡطَعَ دَابِرَ ٱلۡكَٰفِرِينَ ٧","وإذ يعدكم الله إحدى الطائفتين أنها لكم وتودون أن غير ذات الشوكة تكون لكم ويريد الله أن يحق الحق بكلماته ويقطع دابر الكافرين","ދެބައިމީހުންގެ ތެރެއިން (އެބަހީ: ވިޔަފާރި ގާފިލާއާއި، ހަނގުރާމަވެރި ލަޝްކަރުގެތެރެއިން) އެއްބަޔެއްގެ މައްޗަށް ތިޔަބައިމީހުންނަށް ނަސްރު ލިބޭނެ ކަމުގައި، ﷲ ތިޔަބައިމީހުންނަށް ވައުދުކުރެއްވިހިނދު، ހަނދުމަކުރާށެވެ! އަދި ބާރުވެރިކަން ލިބިގެންނުވާ މީހުން، ތިޔަބައިމީހުންނަށްޓަކައި އޮތުމަށް ތިޔަބައިމީހުން އެދެމުއެވެ. (ނަމަވެސް) ﷲ އިރާދަކުރައްވަނީ، އެކަލާނގެ ކަލިމަ ފުޅުތަކުން ހައްގު ސާބިތުކުރައްވައި، ފާޅުކުރެއްވުމަށެވެ. އަދި ކާފިރުންގެ އަޞްލު މުލުން ލުހެލެއްވުމަށެވެ.","",""],["₈ سورة الأَنفال","8","لِيُحِقَّ ٱلۡحَقَّ وَيُبۡطِلَ ٱلۡبَٰطِلَ وَلَوۡ كَرِهَ ٱلۡمُجۡرِمُونَ ٨","ليحق الحق ويبطل الباطل ولو كره المجرمون","(އެއީ) ކުށްވެރިން ނުރުހުނު ކަމުގައިވިޔަސް، ހައްގު ގަދަކުރައްވައި، ބާތިލު ނެތިކުރެއްވުމަށްޓަކައެވެ.","",""],["₈ سورة الأَنفال","9","إِذۡ تَسۡتَغِيثُونَ رَبَّكُمۡ فَٱسۡتَجَابَ لَكُمۡ أَنِّي مُمِدُّكُم بِأَلۡفٖ مِّنَ ٱلۡمَلَـٰٓئِكَةِ مُرۡدِفِينَ ٩","إذ تستغيثون ربكم فاستجاب لكم أني ممدكم بألف من الملائكة مردفين","ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް އެހީއަށްއެދި ތިޔަބައިމީހުން ދެންނެވިހިނދު، ހަނދުމަކުރާށެވެ! ފަހެ، އެހިނދު އެކަލާނގެ ތިޔަބައިމީހުންނަށް އިޖާބަދެއްވައި އެންގެވިއެވެ. މަލާއިކަތުންގެ ހާހަކުން ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް މަދަދު ދެއްވާހުށީމެވެ. އެކަކަށްފަހު އަނެކަކު އަންނަގޮތުގައެވެ.","",""],["₈ سورة الأَنفال","10","وَمَا جَعَلَهُ ٱللَّهُ إِلَّا بُشۡرَىٰ وَلِتَطۡمَئِنَّ بِهِۦ قُلُوبُكُمۡۚ وَمَا ٱلنَّصۡرُ إِلَّا مِنۡ عِندِ ٱللَّهِۚ إِنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌ ١٠","وما جعله الله إلا بشرى ولتطمئن به قلوبكم وما النصر إلا من عند الله إن الله عزيز حكيم","އުފާވެރިކަމުގެ ޚަބަރެއް ކަމުގައްޔާއި، އެކަމުގެ ސަބަބުން ތިޔަބައިމީހުންގެ ހިތްތައް ހަމަޖެހުމަށްޓަކައި މެނުވީ، ﷲ އެކަންތަކެއް ނުލައްވައެވެ. އަދި ﷲގެ ހަޒުރަތުން މެނުވީ، ނަސްރު ލިބުމެއް ނުވެއެވެ. ހަމަކަށަވަރުން، ﷲއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","11","إِذۡ يُغَشِّيكُمُ ٱلنُّعَاسَ أَمَنَةٗ مِّنۡهُ وَيُنَزِّلُ عَلَيۡكُم مِّنَ ٱلسَّمَآءِ مَآءٗ لِّيُطَهِّرَكُم بِهِۦ وَيُذۡهِبَ عَنكُمۡ رِجۡزَ ٱلشَّيۡطَٰنِ وَلِيَرۡبِطَ عَلَىٰ قُلُوبِكُمۡ وَيُثَبِّتَ بِهِ ٱلۡأَقۡدَامَ ١١","إذ يغشيكم النعاس أمنة منه وينزل عليكم من السماء ماء ليطهركم به ويذهب عنكم رجز الشيطان وليربط على قلوبكم ويثبت به الأقدام","އެކަލާނގެ ހަޒުރަތުން އައި އަމާންކަމެއްގެ ގޮތުގައި ނިދިޖެހުން ތިޔަބައިމީހުންގެ މައްޗަށް އެކަލާނގެ ފޮނުއްވައި، އަދި އެކަލާނގެ ތިޔަބައިމީހުން ތާހިރުކުރެއްވުމަށާއި، ޝައިތާނާގެ ވަސްވާސް ތިޔަބައިމީހުންގެ ކިބައިން ފިއްލެވުމަށާއި، ތިޔަބައިމީހުންގެ ހިތްތަކަށް ގަދަކަން ދެއްވުމަށާއި، (ތިޔަބައިމީހުންގެ) ފައިތިލަތައް ސާބިތު ކުރެއްވުމަށްޓަކައި، ތިޔަބައިމީހުންގެ މައްޗަށް އުޑުން ފެން ބާވައިލެއްވިހިނދު، ހަނދުމަކުރާށެވެ!","",""],["₈ سورة الأَنفال","12","إِذۡ يُوحِي رَبُّكَ إِلَى ٱلۡمَلَـٰٓئِكَةِ أَنِّي مَعَكُمۡ فَثَبِّتُواْ ٱلَّذِينَ ءَامَنُواْۚ سَأُلۡقِي فِي قُلُوبِ ٱلَّذِينَ كَفَرُواْ ٱلرُّعۡبَ فَٱضۡرِبُواْ فَوۡقَ ٱلۡأَعۡنَاقِ وَٱضۡرِبُواْ مِنۡهُمۡ كُلَّ بَنَانٖ ١٢","إذ يوحي ربك إلى الملائكة أني معكم فثبتوا الذين آمنوا سألقي في قلوب الذين كفروا الرعب فاضربوا فوق الأعناق واضربوا منهم كل بنان","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ މަލާއިކަތުންނަށް ވަހީކުރެއްވިހިނދު ހަނދުމަކުރާށެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ވޮޑިގެންވަނީ، ތިޔަބައިމީހުންނާ އެކުގައެވެ. ފަހެ، އީމާންވި މީހުންނަށް ސާބިތުކަން ދެއްވާށެވެ! ކާފިރުވި މީހުންގެ ހިތްތަކަށް ތިމަންރަސްކަލާނގެ ބިރުވެރިކަން ވައްދަވާހުށީމެވެ. ފަހެ، ކަނދުރާތަކުގެ މަތީގައި ތިޔަބައިމީހުން (ކަނޑިން) ޖަހާށެވެ! އަދި އެއުރެންގެ ހުރިހާ އިނގިލިކުރިތަކުގައި (ކަނޑިން) ޖަހާށެވެ!","",""],["₈ سورة الأَنفال","13","ذَٰلِكَ بِأَنَّهُمۡ شَآقُّواْ ٱللَّهَ وَرَسُولَهُۥۚ وَمَن يُشَاقِقِ ٱللَّهَ وَرَسُولَهُۥ فَإِنَّ ٱللَّهَ شَدِيدُ ٱلۡعِقَابِ ١٣","ذلك بأنهم شاقوا الله ورسوله ومن يشاقق الله ورسوله فإن الله شديد العقاب","އެއީ އެއުރެން، ﷲއާއި، އެކަލާނގެ ރަސޫލާއަށް ދެކޮޅުވެރިވީ ކަމަށްޓަކައެވެ. ﷲއާއި، އެކަލާނގެ ރަސޫލާއަށް ދެކޮޅުވެރިވާމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، އުގޫބާތް ގަދަފަދަވެގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","14","ذَٰلِكُمۡ فَذُوقُوهُ وَأَنَّ لِلۡكَٰفِرِينَ عَذَابَ ٱلنَّارِ ١٤","ذلكم فذوقوه وأن للكافرين عذاب النار","އެއީ އެކަން އޮތްގޮތެވެ. ފަހެ، ތިޔަބައިމީހުން (އެބަހީ: ކާފިރުން) އެ އަޒާބުގެ ރަހަ ލިބިގަންނާށެވެ! އަދި ހަމަކަށަވަރުން، ކާފިރުވި މީހުންނަށް ނަރަކައިގެ އަޒާބު ހުށްޓެވެ.","",""],["₈ سورة الأَنفال","15","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ إِذَا لَقِيتُمُ ٱلَّذِينَ كَفَرُواْ زَحۡفٗا فَلَا تُوَلُّوهُمُ ٱلۡأَدۡبَارَ ١٥","يا أيها الذين آمنوا إذا لقيتم الذين كفروا زحفا فلا تولوهم الأدبار","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! (ހަނގުރާމައިގެ މައިދާނުގައި) ކުރިމަތިލައި އަންނަނިކޮށް، ކާފިރުވި މީހުންނާ ތިޔަބައިމީހުން ބައްދަލުވާހިނދު، އެއުރެންނަށް ފުރަގަސްދީ ތިޔަބައިމީހުން ނުދާހުށިކަމެވެ!","",""],["₈ سورة الأَنفال","16","وَمَن يُوَلِّهِمۡ يَوۡمَئِذٖ دُبُرَهُۥٓ إِلَّا مُتَحَرِّفٗا لِّقِتَالٍ أَوۡ مُتَحَيِّزًا إِلَىٰ فِئَةٖ فَقَدۡ بَآءَ بِغَضَبٖ مِّنَ ٱللَّهِ وَمَأۡوَىٰهُ جَهَنَّمُۖ وَبِئۡسَ ٱلۡمَصِيرُ ١٦","ومن يولهم يومئذ دبره إلا متحرفا لقتال أو متحيزا إلى فئة فقد باء بغضب من الله ومأواه جهنم وبئس المصير","ހަނގުރާމައަކަށް އުކުޅެއްހަދާމީހެއްގެ ގޮތުގައި، ނުވަތަ (މުއުމިނު) އެހެން ބަޔެއްގެ ފަރާތަށް ޖެހިލާމީހެއްގެ ގޮތުގައި މެނުވީ، އެދުވަހުން ފުރަގަސްދީ ދުރަށްދާމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކު ﷲގެ ކޯފާއާއިގެން އެނބުރި އަތުވެއްޖެކަން ކަށަވަރެވެ. އަދި އެމީހާ އުޅޭނެތަނަކީ، ޖަހައްނަމެވެ. އަދި (އެއީ) ހާދަހާ ނުބައިވެގެންވާ ނިމިދިޔުމެކެވެ.","",""],["₈ سورة الأَنفال","17","فَلَمۡ تَقۡتُلُوهُمۡ وَلَٰكِنَّ ٱللَّهَ قَتَلَهُمۡۚ وَمَا رَمَيۡتَ إِذۡ رَمَيۡتَ وَلَٰكِنَّ ٱللَّهَ رَمَىٰ وَلِيُبۡلِيَ ٱلۡمُؤۡمِنِينَ مِنۡهُ بَلَآءً حَسَنًاۚ إِنَّ ٱللَّهَ سَمِيعٌ عَلِيمٞ ١٧","فلم تقتلوهم ولكن الله قتلهم وما رميت إذ رميت ولكن الله رمى وليبلي المؤمنين منه بلاء حسنا إن الله سميع عليم","ފަހެ، ތިޔަބައިމީހުން އެ ކާފިރުން ގަތުލެއް ނުކުރަމުއެވެ. އެހެނެއްކަމަކު، ﷲ، އެއުރެން ގަތުލުކުރެއްވީއެވެ. (އެބަހީ: ކާފިރުން ގަތުލު ވެގެންދިޔައީ ތިޔަބައިމީހުންގެ ބާރަކުން ނޫނެވެ. ﷲ ދެއްވި ނަސްރުގެ ބާރުންނެވެ.) އަދި ކަލޭގެފާނު (ހިލަ މުށެއް) އުއްކަވައިލެއްވިހިނދު، އުއްކަވައިލެއްވީ ކަލޭގެފާނެއްނޫނެވެ. އެހެނެއްކަމަކު، އުއްކަވައިލެއްވީ، ﷲއެވެ. އަދި އެކަމުން ރިވެތިވެގެންވާ އިމްތިހާނަކުން މުއުމިނުން އިމްތިހާނުކުރެއްވުމަށެވެ. ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","18","ذَٰلِكُمۡ وَأَنَّ ٱللَّهَ مُوهِنُ كَيۡدِ ٱلۡكَٰفِرِينَ ١٨","ذلكم وأن الله موهن كيد الكافرين","އެއީ އެކަން އޮތްގޮތެވެ. އަދި ހަމަކަށަވަރުން، ﷲއީ، ކާފިރުންގެ މަކަރުވެރި ރޭވުންތައް ނިކަމެތިކުރައްވާ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","19","إِن تَسۡتَفۡتِحُواْ فَقَدۡ جَآءَكُمُ ٱلۡفَتۡحُۖ وَإِن تَنتَهُواْ فَهُوَ خَيۡرٞ لَّكُمۡۖ وَإِن تَعُودُواْ نَعُدۡ وَلَن تُغۡنِيَ عَنكُمۡ فِئَتُكُمۡ شَيۡـٔٗا وَلَوۡ كَثُرَتۡ وَأَنَّ ٱللَّهَ مَعَ ٱلۡمُؤۡمِنِينَ ١٩","إن تستفتحوا فقد جاءكم الفتح وإن تنتهوا فهو خير لكم وإن تعودوا نعد ولن تغني عنكم فئتكم شيئا ولو كثرت وأن الله مع المؤمنين","ތިޔަބައިމީހުން (އެބަހީ: ކާފިރުން) އިންސާފަށް އެދޭނަމަ، ފަހެ، ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނާ ހަމަޔަށް ނިޔާ އަތުވެއްޖެއެވެ. އަދި ތިޔަބައިމީހުން (އަދާވަތް ތެރިވުން) ހުއްޓައިލާނަމަ، އެގޮތް ތިޔަބައިމީހުންނަށް ހެޔޮކަން ބޮޑެވެ. އަދި ތިޔަބައިމީހުން، އެނބުރި (އަދާވަތް ތެރިވުމަށް) އަންނަނަމަ، ތިމަންރަސްކަލާނގެ (މުއުމިނުންނަށް ނަސްރު ދެއްވުމަށް) ވޮޑިގެންވާހުށީމެވެ. އަދި ތިޔަބައިމީހުންގެ ބައިގިނަވެގެންވީ ކަމުގައިވިޔަސް، ތިޔަބައިމީހުންނަށްޓަކައި، އެއުރެންނަށް އެއްވެސްކަމެއް ފުއްދައެއް ނުދެވޭނެތެވެ. އަދި ހަމަކަށަވަރުން، ﷲ ވޮޑިގެންވަނީ، މުއުމިނުންނާ އެކުގައެވެ.","",""],["₈ سورة الأَنفال","20","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ أَطِيعُواْ ٱللَّهَ وَرَسُولَهُۥ وَلَا تَوَلَّوۡاْ عَنۡهُ وَأَنتُمۡ تَسۡمَعُونَ ٢٠","يا أيها الذين آمنوا أطيعوا الله ورسوله ولا تولوا عنه وأنتم تسمعون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް ތިޔަބައިމީހުން ކިޔަމަންވާށެވެ! އަދި ތިޔަބައިމީހުން (އެކަލޭގެފާނު ވިދާޅުވާ އެއްޗެއް) އަޑުއަހާންތިބެފައި، އެކަލޭގެފާނަށް ފުރަގަސްނުދޭށެވެ!","",""],["₈ سورة الأَنفال","21","وَلَا تَكُونُواْ كَٱلَّذِينَ قَالُواْ سَمِعۡنَا وَهُمۡ لَا يَسۡمَعُونَ ٢١","ولا تكونوا كالذين قالوا سمعنا وهم لا يسمعون","އަދި ނާހައިތިބެމެ، ތިމަންމެން އަހައިފީމުއޭ ބުނި މީހުން ފަދައިން ތިޔަބައިމީހުން ނުވާށެވެ!","",""],["₈ سورة الأَنفال","22","۞إِنَّ شَرَّ ٱلدَّوَآبِّ عِندَ ٱللَّهِ ٱلصُّمُّ ٱلۡبُكۡمُ ٱلَّذِينَ لَا يَعۡقِلُونَ ٢٢","إن شر الدواب عند الله الصم البكم الذين لا يعقلون","ހަމަކަށަވަރުން، ދިރޭ ތަކެތީގެ ތެރެއިން ﷲގެ ހަޒުރަތުގައި އެންމެ ނުބައިކަން ބޮޑު ބަޔަކީ ބީރު، މަންމަނުންނެވެ. އެއުރެންނީ، ނުވިސްނާ ބަޔެކެވެ. (އެބަހީ: ހައްގުގެބަސް ނުބުނާ، އެ އަޑުނާހާ، ހައްގާއި، ބާތިލު ވަކިކުރުމަށް ވިސްނުމުގެ ބޭނުން ނުކުރާ މީހުންނެވެ.)","",""],["₈ سورة الأَنفال","23","وَلَوۡ عَلِمَ ٱللَّهُ فِيهِمۡ خَيۡرٗا لَّأَسۡمَعَهُمۡۖ وَلَوۡ أَسۡمَعَهُمۡ لَتَوَلَّواْ وَّهُم مُّعۡرِضُونَ ٢٣","ولو علم الله فيهم خيرا لأسمعهم ولو أسمعهم لتولوا وهم معرضون","އެއުރެންގެ ކިބައިގައި، ހެޔޮކަމެއްވާކަން ﷲ ދެނެވޮޑިގެންފިނަމަ، އެއުރެންނަށް އިއްވެވީސްކަން ކަށަވަރެވެ. އަދި އެއުރެންނަށް އިއްވެވި ނަމަވެސް، ފުރަގަސްދޭ ޙާލު، އެއުރެން އެނބުރި ހިނގައްޖައީސްކަން ކަށަވަރެވެ.","",""],["₈ سورة الأَنفال","24","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ ٱسۡتَجِيبُواْ لِلَّهِ وَلِلرَّسُولِ إِذَا دَعَاكُمۡ لِمَا يُحۡيِيكُمۡۖ وَٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ يَحُولُ بَيۡنَ ٱلۡمَرۡءِ وَقَلۡبِهِۦ وَأَنَّهُۥٓ إِلَيۡهِ تُحۡشَرُونَ ٢٤","يا أيها الذين آمنوا استجيبوا لله وللرسول إذا دعاكم لما يحييكم واعلموا أن الله يحول بين المرء وقلبه وأنه إليه تحشرون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންނަށް ދިރުންދޭ ކަމަކަށް ރަސޫލާ ތިޔަބައިމީހުންނަށް ގޮވައިލައްވާހިނދު، ﷲއަށާއި، ރަސޫލާއަށް ތިޔަބައިމީހުން އިޖާބަ ދޭހުށިކަމެވެ! އަދި ތިޔަބައިމީހުން ދަންނާށެވެ! ހަމަކަށަވަރުން، ﷲ، އިންސާނާއާއި، އޭނާގެ ހިތުގެ އެދުންތަކާ ދެމެދު ހުރަސްއަޅުއްވަތެވެ. އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުން (ގިޔާމަތް ދުވަހުން) އެއްކުރައްވާހުށީ، އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["₈ سورة الأَنفال","25","وَٱتَّقُواْ فِتۡنَةٗ لَّا تُصِيبَنَّ ٱلَّذِينَ ظَلَمُواْ مِنكُمۡ خَآصَّةٗۖ وَٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ شَدِيدُ ٱلۡعِقَابِ ٢٥","واتقوا فتنة لا تصيبن الذين ظلموا منكم خاصة واعلموا أن الله شديد العقاب","އަދި ތިޔަބައިމީހުން ފިތުނައަކަށް ބިރުވެތިވެ ރައްކާތެރިވާށެވެ! އެ ފިތުނައައިސް ޖެހިދާހުށީ، ތިޔަބައިމީހުންގެ ތެރެއިން އަނިޔާވެރިވި މީހުންނަށް އެކަންޏެއްނޫނެވެ. އަދި ހަމަކަށަވަރުން، ﷲއީ، އުގޫބާތް ގަދަފަދަވެގެންވާ ކަލާނގެކަން ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₈ سورة الأَنفال","26","وَٱذۡكُرُوٓاْ إِذۡ أَنتُمۡ قَلِيلٞ مُّسۡتَضۡعَفُونَ فِي ٱلۡأَرۡضِ تَخَافُونَ أَن يَتَخَطَّفَكُمُ ٱلنَّاسُ فَـَٔاوَىٰكُمۡ وَأَيَّدَكُم بِنَصۡرِهِۦ وَرَزَقَكُم مِّنَ ٱلطَّيِّبَٰتِ لَعَلَّكُمۡ تَشۡكُرُونَ ٢٦","واذكروا إذ أنتم قليل مستضعفون في الأرض تخافون أن يتخطفكم الناس فآواكم وأيدكم بنصره ورزقكم من الطيبات لعلكم تشكرون","ބިމުގައި ތިޔަބައިމީހުން އަދަދު މަދު، ނިކަމެތި ބަޔަކު ކަމުގައި ވީހިނދު، ހަނދުމަކުރާށެވެ! (އެހިނދު) ތިޔަބައިމީހުންތިބީ (އަދާވަތް ތެރި) މީހުން ތިޔަބައިމީހުން ޖަހައިގަނެގެން ގެންގޮސްފާނެކަމަށް ބިރުގެންފައެވެ. ދެން އެކަލާނގެ ތިޔަބައިމީހުންނަށް ހިޔާވަހިކަން ދެއްވިއެވެ. އަދި އެކަލާނގެ ނަސްރުން ތިޔަބައިމީހުންނަށް ގަދަކަން ދެއްވިއެވެ. އަދި ރަނގަޅު ތަކެތިން ތިޔަބައިމީހުންނަށް ރިޒްގު ދެއްވިއެވެ. (އެއީ) ތިޔަބައިމީހުން ޝުކުރުވެރިވުމަށްޓަކައެވެ.","",""],["₈ سورة الأَنفال","27","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تَخُونُواْ ٱللَّهَ وَٱلرَّسُولَ وَتَخُونُوٓاْ أَمَٰنَٰتِكُمۡ وَأَنتُمۡ تَعۡلَمُونَ ٢٧","يا أيها الذين آمنوا لا تخونوا الله والرسول وتخونوا أماناتكم وأنتم تعلمون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ﷲއަށާއި، ރަސޫލާއަށް ތިޔަބައިމީހުން ޚިޔާނަތް ތެރި ނުވާށެވެ! އަދި ތިޔަބައިމީހުންގެ އަމާނަތްތަކަށް، އެނގިއެނގިތިބެ ތިޔަބައިމީހުން ޚިޔާނަތް ތެރި ނުވާށެވެ!","",""],["₈ سورة الأَنفال","28","وَٱعۡلَمُوٓاْ أَنَّمَآ أَمۡوَٰلُكُمۡ وَأَوۡلَٰدُكُمۡ فِتۡنَةٞ وَأَنَّ ٱللَّهَ عِندَهُۥٓ أَجۡرٌ عَظِيمٞ ٢٨","واعلموا أنما أموالكم وأولادكم فتنة وأن الله عنده أجر عظيم","އަދި ތިޔަބައިމީހުން ދަންނާށެވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ މުދާތަކާއި، ތިޔަބައިމީހުންގެ ދަރިންނަކީ، އިމްތިހާނެކެވެ. އަދި ހަމަކަށަވަރުން، ބޮޑުވެގެންވާ ދަރުމަ ވަނީ، ﷲގެ ހަޒުރަތު ގައެވެ.","",""],["₈ سورة الأَنفال","29","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ إِن تَتَّقُواْ ٱللَّهَ يَجۡعَل لَّكُمۡ فُرۡقَانٗا وَيُكَفِّرۡ عَنكُمۡ سَيِّـَٔاتِكُمۡ وَيَغۡفِرۡ لَكُمۡۗ وَٱللَّهُ ذُو ٱلۡفَضۡلِ ٱلۡعَظِيمِ ٢٩","يا أيها الذين آمنوا إن تتقوا الله يجعل لكم فرقانا ويكفر عنكم سيئاتكم ويغفر لكم والله ذو الفضل العظيم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން، ﷲއަށް ތަގުވާވެރިވާނަމަ، ތިޔަބައިމީހުންނަށް ހައްގާއި، ބާތިލު ވަކިކުރާނެ މަގު، އެކަލާނގެ ދައްކަވާނެތެވެ. އަދި ތިޔަބައިމީހުންގެ ކިބައިން ކުށްފާފަތައް ފިއްލަވާނެތެވެ. އަދި ތިޔަބައިމީހުންނަށް ފާފަފުއްސަވާނެތެވެ. ﷲއީ، ބޮޑުވެގެންވާ ފަޟްލު ވަންތަކަމުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","30","وَإِذۡ يَمۡكُرُ بِكَ ٱلَّذِينَ كَفَرُواْ لِيُثۡبِتُوكَ أَوۡ يَقۡتُلُوكَ أَوۡ يُخۡرِجُوكَۚ وَيَمۡكُرُونَ وَيَمۡكُرُ ٱللَّهُۖ وَٱللَّهُ خَيۡرُ ٱلۡمَٰكِرِينَ ٣٠","وإذ يمكر بك الذين كفروا ليثبتوك أو يقتلوك أو يخرجوك ويمكرون ويمكر الله والله خير الماكرين","ކާފިރުވި މީހުން، ކަލޭގެފާނު ހައްޔަރުކުރުމަށް، ނުވަތަ އަވަހާރަކޮށްލުމަށް، ނުވަތަ ކަލޭގެފާނު ރަށުން ބޭރުކޮށްލުމަށް ރޭވިހިނދު، ހަނދުމަކުރައްވާށެވެ! އެއުރެން މަކަރުވެރި، ނުބައި ރޭވުންތައް ރާވަތެވެ. އަދި ﷲ (އެއުރެންގެ ރޭވުންތައް، ބާތިލުކުރައްވައި، އެއުރެންނަށް ކެހިލިބޭނެގޮތަށް) ތަދްބީރުކުރައްވަތެވެ. ﷲއީ، މަކަރުވެރިންނަށްވުރެ، ތަދްބީރުކުރެއްވުން މޮޅު ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","31","وَإِذَا تُتۡلَىٰ عَلَيۡهِمۡ ءَايَٰتُنَا قَالُواْ قَدۡ سَمِعۡنَا لَوۡ نَشَآءُ لَقُلۡنَا مِثۡلَ هَٰذَآ إِنۡ هَٰذَآ إِلَّآ أَسَٰطِيرُ ٱلۡأَوَّلِينَ ٣١","وإذا تتلى عليهم آياتنا قالوا قد سمعنا لو نشاء لقلنا مثل هذا إن هذا إلا أساطير الأولين","އަދި އެއުރެންނަށް، ތިމަންރަސްކަލާނގެ އާޔަތްތައް ބަޔާންވެގެންވާ ގޮތުގައި ކިޔައިދެއްވާހިނދު، އެއުރެން ބުނެތެވެ. ހަމަކަށަވަރުން، ތިމަންމެން ތިޔަ އަޑުއެހީމުއެވެ. ތިމަންމެން އެދޭނަމަ، ތިމަންމެންވެސް ތިޔަކަހަލަ ބަސްތަކެއް ކިޔައިފީމުހެވެ. ތިޔައީ، އެވޭލާ މީހުންގެ ފުލޯކު ވާހަކަތަކެއް ކަމުގައި މެނުވީ ނުވެއެވެ.","",""],["₈ سورة الأَنفال","32","وَإِذۡ قَالُواْ ٱللَّهُمَّ إِن كَانَ هَٰذَا هُوَ ٱلۡحَقَّ مِنۡ عِندِكَ فَأَمۡطِرۡ عَلَيۡنَا حِجَارَةٗ مِّنَ ٱلسَّمَآءِ أَوِ ٱئۡتِنَا بِعَذَابٍ أَلِيمٖ ٣٢","وإذ قالوا اللهم إن كان هذا هو الحق من عندك فأمطر علينا حجارة من السماء أو ائتنا بعذاب أليم","އަދި އެއުރެން ބުނިހިނދު ހަނދުމަކުރާށެވެ! އޭ ހައްދަވާ ބޮޑުކުރެއްވި ރަސްކަލާކޯއެވެ! މިއީ، އިބަރަސްކަލާނގެ ހަޒުރަތުން އައި ހައްގު ބަސްފުޅު ކަމުގައިވާނަމަ، ފަހެ، އަޅަމެންގެ މައްޗަށް އުޑުން ހިލަތަކެއް ވެއްސަވައިފާނދޭވެ! ނުވަތަ އަޅަމެންނަށް ވޭންދެނިވި އަޒާބެއް ދެއްވައިފާނދޭވެ!","",""],["₈ سورة الأَنفال","33","وَمَا كَانَ ٱللَّهُ لِيُعَذِّبَهُمۡ وَأَنتَ فِيهِمۡۚ وَمَا كَانَ ٱللَّهُ مُعَذِّبَهُمۡ وَهُمۡ يَسۡتَغۡفِرُونَ ٣٣","وما كان الله ليعذبهم وأنت فيهم وما كان الله معذبهم وهم يستغفرون","އަދި ކަލޭގެފާނު އެއުރެންގެ މެދުގައި ހުންނަވަނިކޮށް، ﷲ، އެއުރެންނަކަށް އަޒާބެއް ނުދެއްވާނެތެވެ. އަދި އެއުރެން އިސްތިޣްފާރު ކޮށްކޮށް ތިއްބައި، ﷲ، އެއުރެންނަކަށް އަޒާބެއް ނުދެއްވާނެތެވެ.","",""],["₈ سورة الأَنفال","34","وَمَا لَهُمۡ أَلَّا يُعَذِّبَهُمُ ٱللَّهُ وَهُمۡ يَصُدُّونَ عَنِ ٱلۡمَسۡجِدِ ٱلۡحَرَامِ وَمَا كَانُوٓاْ أَوۡلِيَآءَهُۥٓۚ إِنۡ أَوۡلِيَآؤُهُۥٓ إِلَّا ٱلۡمُتَّقُونَ وَلَٰكِنَّ أَكۡثَرَهُمۡ لَا يَعۡلَمُونَ ٣٤","وما لهم ألا يعذبهم الله وهم يصدون عن المسجد الحرام وما كانوا أولياءه إن أولياؤه إلا المتقون ولكن أكثرهم لا يعلمون","އެއުރެންނަށް ﷲ، އަޒާބު ނުދެއްވުމަށް އެއުރެންނަށް އޮތީ ކޮން ޢުޛުރެއް ހެއްޔެވެ؟ އެއުރެން އެތިބަ ހުރުމަތް ތެރިވެގެންވާ މިސްކިތުން (މީސްތަކުން) ދުރުކުރަނީއެވެ. އެއުރެންނަކީ، އެތާނގެ ބެލެހެއްޓުންތެރިންނެއްވެސް ނޫނެވެ. ތަގުވާވެރިން މެނުވީ އެތާނގެ ބެލެހެއްޓުންތެރިން ކަމުގައި ނުވެތެވެ. އެހެނެއްކަމަކު، އެއުރެންކުރެ ގިނަމީހުންނަކަށް (އެކަމެއް) ނޭނގެތެވެ.","",""],["₈ سورة الأَنفال","35","وَمَا كَانَ صَلَاتُهُمۡ عِندَ ٱلۡبَيۡتِ إِلَّا مُكَآءٗ وَتَصۡدِيَةٗۚ فَذُوقُواْ ٱلۡعَذَابَ بِمَا كُنتُمۡ تَكۡفُرُونَ ٣٥","وما كان صلاتهم عند البيت إلا مكاء وتصدية فذوقوا العذاب بما كنتم تكفرون","ގެފުޅުގެ އަރިހުގައި އެއުރެންކުރާ އަޅުކަމަކީ، ތުބުންފުމުމާއި، އަތްތިލަބަޑިޖެހުން ކަމުގައި މެނުވީ ނުވެތެވެ. ފަހެ، ތިޔަބައިމީހުން ކާފިރުވެ އުޅުނުކަމުގެ ސަބަބުން، ތިޔަބައިމީހުން އަޒާބުގެ ރަހަ ލިބިގަންނާށެވެ!","",""],["₈ سورة الأَنفال","36","إِنَّ ٱلَّذِينَ كَفَرُواْ يُنفِقُونَ أَمۡوَٰلَهُمۡ لِيَصُدُّواْ عَن سَبِيلِ ٱللَّهِۚ فَسَيُنفِقُونَهَا ثُمَّ تَكُونُ عَلَيۡهِمۡ حَسۡرَةٗ ثُمَّ يُغۡلَبُونَۗ وَٱلَّذِينَ كَفَرُوٓاْ إِلَىٰ جَهَنَّمَ يُحۡشَرُونَ ٣٦","إن الذين كفروا ينفقون أموالهم ليصدوا عن سبيل الله فسينفقونها ثم تكون عليهم حسرة ثم يغلبون والذين كفروا إلى جهنم يحشرون","ހަމަކަށަވަރުން، ކާފިރުވި މީހުން، ﷲގެ މަގުން މީސްތަކުން ދުރުކުރުމަށް، އެއުރެންގެ މުދާތައް ހޭދަކުރެތެވެ. ފަހެ، އެއުރެން އެތަކެތި ހޭދަކުރަމުން ގެންދާނެތެވެ. ދެން އެ މުދާތައް، އެއުރެންގެ މައްޗަށް ހުރި ހިތާމަޔަކަށް ވެގެންދާނެތެވެ. ދެން އެއުރެން ބަލިކުރައްވާނެތެވެ. އަދި ކާފިރުވިމީހުން ނަރަކައަށް ޖަމާކުރައްވާނެތެވެ.","",""],["₈ سورة الأَنفال","37","لِيَمِيزَ ٱللَّهُ ٱلۡخَبِيثَ مِنَ ٱلطَّيِّبِ وَيَجۡعَلَ ٱلۡخَبِيثَ بَعۡضَهُۥ عَلَىٰ بَعۡضٖ فَيَرۡكُمَهُۥ جَمِيعٗا فَيَجۡعَلَهُۥ فِي جَهَنَّمَۚ أُوْلَـٰٓئِكَ هُمُ ٱلۡخَٰسِرُونَ ٣٧","ليميز الله الخبيث من الطيب ويجعل الخبيث بعضه على بعض فيركمه جميعا فيجعله في جهنم أولئك هم الخاسرون","(އެއީ) ﷲ، ރަނގަޅު މީހުންނާއި، ނުބައި މީހުން ވަކިކުރައްވައި، ނުބައި މީހުން އެކަކުގެ މައްޗަށް އަނެކަކު ލައްވައި، އެންމެން އެކުގައި ފުނިޖައްސަވައި، ނަރަކައިގެތެރެއަށް ލެއްވުމަށްޓަކައެވެ. އެއުރެންނީ ހަމަ، ގެއްލެނިވެގެންވާ މީހުންނެވެ.","",""],["₈ سورة الأَنفال","38","قُل لِّلَّذِينَ كَفَرُوٓاْ إِن يَنتَهُواْ يُغۡفَرۡ لَهُم مَّا قَدۡ سَلَفَ وَإِن يَعُودُواْ فَقَدۡ مَضَتۡ سُنَّتُ ٱلۡأَوَّلِينَ ٣٨","قل للذين كفروا إن ينتهوا يغفر لهم ما قد سلف وإن يعودوا فقد مضت سنت الأولين","ކާފިރުވި މީހުންނަށް، ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއުރެން (ހަނގުރާމަކުރުމާއި، ކާފިރު ކަން) ހުއްޓާލައިފިނަމަ، އެއުރެންނަށް އިސްވެގޮސްފައިވާ ފާފަތައް ފުއްސަވާހުށްޓެވެ. އަދި އެއުރެން (އެކަންކަމަށް) އަލުން އެނބުރި އަންނަނަމަ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އިސްވެދިޔަ މީހުންނަށް ވެގެންދިޔަގޮތުގެ މިސާލު ފާއިތުވެ ހިނގައްޖެއެވެ.","",""],["₈ سورة الأَنفال","39","وَقَٰتِلُوهُمۡ حَتَّىٰ لَا تَكُونَ فِتۡنَةٞ وَيَكُونَ ٱلدِّينُ كُلُّهُۥ لِلَّهِۚ فَإِنِ ٱنتَهَوۡاْ فَإِنَّ ٱللَّهَ بِمَا يَعۡمَلُونَ بَصِيرٞ ٣٩","وقاتلوهم حتى لا تكون فتنة ويكون الدين كله لله فإن انتهوا فإن الله بما يعملون بصير","ފިތުނަވެރިކަމާއި، ކާފިރު ކަން ހުއްޓި، މުޅި ދީން ވަނީ، ﷲއަށްޓަކާ ކަމުގައި ހިމެނިއްޖައުމަށްދާނދެން، ތިޔަބައިމީހުން އެ ކާފިރުންނާ ހަނގުރާމަކުރަމުން ގެންދާށެވެ! ފަހެ، އެއުރެން ހުއްޓާލައިފިނަމަ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، އެއުރެންކުރާ ކަންތައް، މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","40","وَإِن تَوَلَّوۡاْ فَٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ مَوۡلَىٰكُمۡۚ نِعۡمَ ٱلۡمَوۡلَىٰ وَنِعۡمَ ٱلنَّصِيرُ ٤٠","وإن تولوا فاعلموا أن الله مولاكم نعم المولى ونعم النصير","އަދި އެއުރެން (ހަނގުރާމައަށް) އެނބުރިގެންފިނަމަ، ހަމަކަށަވަރުން، ﷲއީ، ތިޔަބައިމީހުންނަށް ނަސްރު ދެއްވާ އެހީތެރިވަންތަ ރަސްކަލާނގެކަން ތިޔަބައިމީހުން ދަންނާށެވެ! އެހީތެރިވެވޮޑިގެންވާ ކަލާނގެ މޮޅުކަމާއެވެ! އަދި ނަސްރު ދެއްވާ ކަލާނގެ މޮޅުކަމާއެވެ!","",""],["₈ سورة الأَنفال","41","۞وَٱعۡلَمُوٓاْ أَنَّمَا غَنِمۡتُم مِّن شَيۡءٖ فَأَنَّ لِلَّهِ خُمُسَهُۥ وَلِلرَّسُولِ وَلِذِي ٱلۡقُرۡبَىٰ وَٱلۡيَتَٰمَىٰ وَٱلۡمَسَٰكِينِ وَٱبۡنِ ٱلسَّبِيلِ إِن كُنتُمۡ ءَامَنتُم بِٱللَّهِ وَمَآ أَنزَلۡنَا عَلَىٰ عَبۡدِنَا يَوۡمَ ٱلۡفُرۡقَانِ يَوۡمَ ٱلۡتَقَى ٱلۡجَمۡعَانِۗ وَٱللَّهُ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٌ ٤١","واعلموا أنما غنمتم من شيء فأن لله خمسه وللرسول ولذي القربى واليتامى والمساكين وابن السبيل إن كنتم آمنتم بالله وما أنزلنا على عبدنا يوم الفرقان يوم التقى الجمعان والله على كل شيء قدير","ތިޔަބައިމީހުން ދަންނާށެވެ! ތިޔަބައިމީހުން ޣަނީމާކުޅަ މުދަލެއްގެ ފަސްބައިކުޅަ އެއްބައިވަނީ ﷲއަށާއި، (އެކަލާނގެ) ރަސޫލާއަށާއި، (އެކަލޭގެފާނުގެ) ގާތްތިމާގެ މީހުންނަށާއި، ޔަތީމުންނަށާއި، މިސްކީނުންނަށާއި، ދަތުރުވެރިންނަށެވެ. (އެއީ) ﷲއަށާއި، ހައްގާއި، ބާތިލު ވަކިވުމުގެ ދުވަހު، ދެ ލަޝްކަރު ބައްދަލުވީ ދުވަހު، ތިމަންރަސްކަލާނގެ އަޅާގެ މައްޗަށް ބާވައިލެއްވި ތަކެއްޗަށް، ތިޔަބައިމީހުން އީމާންވާ ކަމުގައިވާނަމައެވެ. ﷲއީ، ކޮންމެ ކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ. (ނޯޓު: ގިނަ މުފައްސިރުން އެއްބަސްވެވަޑައިގަންނަވާ ގޮތުގައި، ޣަނީމާ މުދާ ބެހެނީ ފަސްބަޔަކަށެވެ. އޭގެތެރެއިން ހަތަރުބައި ލިބެނީ، ހަނގުރާމައިގައި ބައިވެރިވި މުސްލިމުންނަށެވެ. އަނެއްބައި ހާއްސަކުރެވިގެންވަނީ، މި އާޔަތުގައި ނަންގަނެވިގެންވާ ފަސްބަޔަކަށެވެ. ﷲއާއި، ރަސޫލާގެ ބައި އެއީ އެއްބައެކެވެ.)","",""],["₈ سورة الأَنفال","42","إِذۡ أَنتُم بِٱلۡعُدۡوَةِ ٱلدُّنۡيَا وَهُم بِٱلۡعُدۡوَةِ ٱلۡقُصۡوَىٰ وَٱلرَّكۡبُ أَسۡفَلَ مِنكُمۡۚ وَلَوۡ تَوَاعَدتُّمۡ لَٱخۡتَلَفۡتُمۡ فِي ٱلۡمِيعَٰدِ وَلَٰكِن لِّيَقۡضِيَ ٱللَّهُ أَمۡرٗا كَانَ مَفۡعُولٗا لِّيَهۡلِكَ مَنۡ هَلَكَ عَنۢ بَيِّنَةٖ وَيَحۡيَىٰ مَنۡ حَيَّ عَنۢ بَيِّنَةٖۗ وَإِنَّ ٱللَّهَ لَسَمِيعٌ عَلِيمٌ ٤٢","إذ أنتم بالعدوة الدنيا وهم بالعدوة القصوى والركب أسفل منكم ولو تواعدتم لاختلفتم في الميعاد ولكن ليقضي الله أمرا كان مفعولا ليهلك من هلك عن بينة ويحيى من حي عن بينة وإن الله لسميع عليم","ތިޔަބައިމީހުން (ބަދުރުގެވާދީގެ) ކައިރިފަރާތުގައި، އަދި އެއުރެން ދުރުފަރާތުގައި، އަދި ވިޔަފާރި ގާފިލާ ތިޔަބައިމީހުންނަށްވުރެ ތިރީ ބިމުގައިވީހިނދު، ހަނދުމަކުރާށެވެ! ތިޔަބައިމީހުން (އެ ކާފިރުންގެ ލަޝްކަރާ ހަނގުރާމަ ކުރުމަށް) އެއްބަޔަކު އަނެއްބަޔަކަށް ވައުދު ވީ ނަމަވެސް، ތިޔަބައިމީހުން އެ ވައުދު ވީގޮތާ ޚިލާފު ވީހެވެ. އެހެނެއްކަމަކު (ދެ ލަޝްކަރު ބައްދަލުކުރުއްވީ) ﷲ ނިޔާކުރައްވާފައިވާ ކަމެއް ހަމަޖެހި، ނިމިގެން ދިޔުމަށްޓަކައެވެ. (އެއީ) ހަލާކުވެގެންދާ ބަޔަކު ސާފު ހެތްކާއެކު، ހަލާކުވެގެން ދިޔުމަށެވެ. އަދި ދިރިގެން އަންނާނޭ ބަޔަކު، ސާފު ހެތްކާއެކު، ދިރިގެން އައުމަށެވެ. ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["₈ سورة الأَنفال","43","إِذۡ يُرِيكَهُمُ ٱللَّهُ فِي مَنَامِكَ قَلِيلٗاۖ وَلَوۡ أَرَىٰكَهُمۡ كَثِيرٗا لَّفَشِلۡتُمۡ وَلَتَنَٰزَعۡتُمۡ فِي ٱلۡأَمۡرِ وَلَٰكِنَّ ٱللَّهَ سَلَّمَۚ إِنَّهُۥ عَلِيمُۢ بِذَاتِ ٱلصُّدُورِ ٤٣","إذ يريكهم الله في منامك قليلا ولو أراكهم كثيرا لفشلتم ولتنازعتم في الأمر ولكن الله سلم إنه عليم بذات الصدور","ﷲ، އެއުރެން (އެބަހީ: މުޝްރިކުންގެ ލަޝްކަރު) މަދު މީސްކޮޅެއްގެ ގޮތުގައި ކަލޭގެފާނަށް ހުވަފެންފުޅުގައި ދެއްކެވިހިނދު، ހަނދުމަކުރާށެވެ! އަދި އެއުރެން ގިނަބަޔަކު ކަމުގައި ދެއްކެވިނަމަ، ތިޔަބައިމީހުން ފިނޑިވެއްޖައީސްކަން ކަށަވަރެވެ. އަދި އެ ހަނގުރާމަކުރުމާމެދު، ތިޔަބައިމީހުން ދެބަސްވެގަންނަން ޖެހުނީސްކަން ކަށަވަރެވެ. ނަމަވެސް، ﷲ (ތިޔަބައިމީހުން) ސަލާމަތްކުރެއްވިއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ހިތްތަކުގައި ވާހާ ކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","44","وَإِذۡ يُرِيكُمُوهُمۡ إِذِ ٱلۡتَقَيۡتُمۡ فِيٓ أَعۡيُنِكُمۡ قَلِيلٗا وَيُقَلِّلُكُمۡ فِيٓ أَعۡيُنِهِمۡ لِيَقۡضِيَ ٱللَّهُ أَمۡرٗا كَانَ مَفۡعُولٗاۗ وَإِلَى ٱللَّهِ تُرۡجَعُ ٱلۡأُمُورُ ٤٤","وإذ يريكموهم إذ التقيتم في أعينكم قليلا ويقللكم في أعينهم ليقضي الله أمرا كان مفعولا وإلى الله ترجع الأمور","އަދި ތިޔަބައިމީހުން (ދެ ލަޝްކަރު) ބައްދަލުވީހިނދު، އެކަލާނގެ ތިޔަބައިމީހުންގެ ލޯތަކަށް އެއުރެން މަދު މީސްކޮޅެއްގެ ގޮތުގައި، ދައްކަވައި އަދި އެއުރެންގެ ލޯތަކަށް ތިޔަބައިމީހުން މަދުކުރެއްވިހިނދު، ހަނދުމަކުރާށެވެ! އެއީ އެކަލާނގެ ނިޔާކުރައްވާފައިވާ ކަމެއް ނިމިގެން ދިޔުމަށްޓަކައެވެ. އަދި އެންމެހާ ކަންތައް ރުޖޫއަކުރައްވާހުށީ، ﷲގެ ހަޒުރަތަށެވެ.","",""],["₈ سورة الأَنفال","45","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ إِذَا لَقِيتُمۡ فِئَةٗ فَٱثۡبُتُواْ وَٱذۡكُرُواْ ٱللَّهَ كَثِيرٗا لَّعَلَّكُمۡ تُفۡلِحُونَ ٤٥","يا أيها الذين آمنوا إذا لقيتم فئة فاثبتوا واذكروا الله كثيرا لعلكم تفلحون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން (ކާފިރުންގެ ހަނގުރާމަވެރި) ބަޔަކާ ބައްދަލުވެއްޖެނަމަ ސާބިތުވެ ތިބޭހުށިކަމެވެ! އަދި ގިނަގިނައިން ﷲ ހަނދުމަކުރާށެވެ! (އެއީ) ތިޔަބައިމީހުން ދިންނަވައި ނަސީބު ލިބުމަށްޓަކައެވެ.","",""],["₈ سورة الأَنفال","46","وَأَطِيعُواْ ٱللَّهَ وَرَسُولَهُۥ وَلَا تَنَٰزَعُواْ فَتَفۡشَلُواْ وَتَذۡهَبَ رِيحُكُمۡۖ وَٱصۡبِرُوٓاْۚ إِنَّ ٱللَّهَ مَعَ ٱلصَّـٰبِرِينَ ٤٦","وأطيعوا الله ورسوله ولا تنازعوا فتفشلوا وتذهب ريحكم واصبروا إن الله مع الصابرين","އަދި ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް ތިޔަބައިމީހުން ކިޔަމަންވާށެވެ! އަދި ތިޔަބައިމީހުން ދެބަސްވެ އަރާރުންނުވާށެވެ! (ދެބަސްވެ އަރާރުންވާނަމަ) ތިޔަބައިމީހުން ފިނޑިވެ، ތިޔަބައިމީހުންގެ ބާރުނެތި ހިނގައިދާނެއެވެ. އަދި ތިޔަބައިމީހުން ކެތްތެރިވާށެވެ! ހަމަކަށަވަރުން، ﷲ ވޮޑިގެންވަނީ، ކެތްތެރިންނާ އެކުގައެވެ.","",""],["₈ سورة الأَنفال","47","وَلَا تَكُونُواْ كَٱلَّذِينَ خَرَجُواْ مِن دِيَٰرِهِم بَطَرٗا وَرِئَآءَ ٱلنَّاسِ وَيَصُدُّونَ عَن سَبِيلِ ٱللَّهِۚ وَٱللَّهُ بِمَا يَعۡمَلُونَ مُحِيطٞ ٤٧","ولا تكونوا كالذين خرجوا من ديارهم بطرا ورئاء الناس ويصدون عن سبيل الله والله بما يعملون محيط","ބޮޑާވެ، މީސްތަކުންނަށް ކަންދެއްކުމުގެ ގޮތުން، އަދި ﷲގެ މަގުން މީސްތަކުން ދުރުކުރާ ޙާލު، އެއުރެންގެ ގެދޮރުން ނުކުމެގެންދިޔަ މީހުން ފަދައިން ތިޔަބައިމީހުން ނުވާށެވެ! ﷲއީ، އެއުރެންކުރާ ޢަމަލުތައް ފުރިހަމަޔަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","48","وَإِذۡ زَيَّنَ لَهُمُ ٱلشَّيۡطَٰنُ أَعۡمَٰلَهُمۡ وَقَالَ لَا غَالِبَ لَكُمُ ٱلۡيَوۡمَ مِنَ ٱلنَّاسِ وَإِنِّي جَارٞ لَّكُمۡۖ فَلَمَّا تَرَآءَتِ ٱلۡفِئَتَانِ نَكَصَ عَلَىٰ عَقِبَيۡهِ وَقَالَ إِنِّي بَرِيٓءٞ مِّنكُمۡ إِنِّيٓ أَرَىٰ مَا لَا تَرَوۡنَ إِنِّيٓ أَخَافُ ٱللَّهَۚ وَٱللَّهُ شَدِيدُ ٱلۡعِقَابِ ٤٨","وإذ زين لهم الشيطان أعمالهم وقال لا غالب لكم اليوم من الناس وإني جار لكم فلما تراءت الفئتان نكص على عقبيه وقال إني بريء منكم إني أرى ما لا ترون إني أخاف الله والله شديد العقاب","އެއުރެންގެ (ނުބައި) ޢަމަލު ތަކަކީ، ޒީނަތްތެރި ޢަމަލު ތަކެއް ކަމުގައި ޝައިތާނާ އެއުރެންނަށް ދެއްކިހިނދު، ހަނދުމަކުރާށެވެ! އަދި އެކަލޭގެ (އެއުރެންނަށް) ބުންޏެވެ. މިއަދު ތިޔަބައިމީހުންގެ މައްޗަށް ގަދަވެގަންނާނޭ އެއްވެސް މީހަކު، މީސްތަކުންގެ ތެރެޔަކުން ނުވެތެވެ. އަދި ހަމަކަށަވަރުން، ތިމަން މިހުރީ ތިޔަބައިމީހުންގެ ރައްކާތެރިޔަކަށެވެ. ފަހެ، ދެ ލަޝްކަރު، އެއްބަޔަކު، އަނެއްބަޔަކަށް ފެނިގެން އައިހިނދު، އެކަލޭގެ ފުރަގަސްދީ ފިލަން ދުއްވައިގަތެވެ. އަދި އެކަލޭގެ ބުންޏެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ކިބައިން ތިމަން ބަރީއަވެގެންވަމެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށް ނުފެންނަ ކަންތައް، ތިމަންނާއަށް އެބަފެނެއެވެ. ހަމަކަށަވަރުން، ﷲއަށް ތިމަން ބިރުގަނެއެވެ. އަދި ﷲއީ، އުގޫބާތް ގަދަފަދަވެގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","49","إِذۡ يَقُولُ ٱلۡمُنَٰفِقُونَ وَٱلَّذِينَ فِي قُلُوبِهِم مَّرَضٌ غَرَّ هَـٰٓؤُلَآءِ دِينُهُمۡۗ وَمَن يَتَوَكَّلۡ عَلَى ٱللَّهِ فَإِنَّ ٱللَّهَ عَزِيزٌ حَكِيمٞ ٤٩","إذ يقول المنافقون والذين في قلوبهم مرض غر هؤلاء دينهم ومن يتوكل على الله فإن الله عزيز حكيم","މުނާފިގްނާއި، އެއުރެންގެ ހިތްތަކުގައި (ކުފުރުގެ) ބަލިމަޑުކަމެއްވާ މީހުން ބުނިހިނދު ހަނދުމަކުރާށެވެ! މިބައިމީހުންގެ (އެބަހީ: މުސްލިމުންގެ) ދީނެއުރެން ހެއްލުންތެރިކޮށްފިއެވެ. އަދި ﷲއަށް ވަކީލުކުރާ މީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","50","وَلَوۡ تَرَىٰٓ إِذۡ يَتَوَفَّى ٱلَّذِينَ كَفَرُواْ ٱلۡمَلَـٰٓئِكَةُ يَضۡرِبُونَ وُجُوهَهُمۡ وَأَدۡبَٰرَهُمۡ وَذُوقُواْ عَذَابَ ٱلۡحَرِيقِ ٥٠","ولو ترى إذ يتوفى الذين كفروا الملائكة يضربون وجوههم وأدبارهم وذوقوا عذاب الحريق","މަލާއިކަތުން، ކާފިރުވި މީހުންގެ މަރު ހިއްޕަވާހިނދު، ކަލޭގެފާނަށް ފެނިވަޑައިގަންނަވާނެ ނަމައެވެ. އެއުރެންގެ މޫނުތަކުގައްޔާއި، ބުރިކަށި ތަކުގައި އެ މަލާއިކަތުން ތަޅުއްވާ ޙާލު ގައެވެ. އަދި (އެހިނދު އެ މަލާއިކަތުން ވިދާޅުވާނެތެވެ.) ތިޔަބައިމީހުން އަނދައަނދާހުރި އަލިފާނުގެ އަޒާބުގެ ރަހަ ލިބިގަންނާށެވެ!","",""],["₈ سورة الأَنفال","51","ذَٰلِكَ بِمَا قَدَّمَتۡ أَيۡدِيكُمۡ وَأَنَّ ٱللَّهَ لَيۡسَ بِظَلَّـٰمٖ لِّلۡعَبِيدِ ٥١","ذلك بما قدمت أيديكم وأن الله ليس بظلام للعبيد","އެއީ ތިޔަބައިމީހުންގެ އަތްތަކުން އިސްކުޅަ ކަންތަކުގެ ސަބަބުންނެވެ. އަދި ހަމަކަށަވަރުން، ﷲއީ، އަޅުތަކުންނަށް އަނިޔާވެރިވެވޮޑިގެންވާ ކަލަކު ކަމުގައި ނުވެތެވެ.","",""],["₈ سورة الأَنفال","52","كَدَأۡبِ ءَالِ فِرۡعَوۡنَ وَٱلَّذِينَ مِن قَبۡلِهِمۡۚ كَفَرُواْ بِـَٔايَٰتِ ٱللَّهِ فَأَخَذَهُمُ ٱللَّهُ بِذُنُوبِهِمۡۚ إِنَّ ٱللَّهَ قَوِيّٞ شَدِيدُ ٱلۡعِقَابِ ٥٢","كدأب آل فرعون والذين من قبلهم كفروا بآيات الله فأخذهم الله بذنوبهم إن الله قوي شديد العقاب","(އެއުރެންގެ އާދަ ވީ) ފިރްޢައުނުގެ މީހުންނާއި، އެއުރެންގެ ކުރިންއުޅުނު (ނުބައި) މީހުންގެ އާދަ ފަދައިންނެވެ. އެއުރެންވެސް ﷲގެ އާޔަތްތަކަށް ކާފިރު ވިއެވެ. ފަހެ، އެއުރެންގެ ފާފަތަކުގެ ސަބަބުން ﷲއެއުރެން ހަލާކު ކުރެއްވިއެވެ. ހަމަކަށަވަރުން، ﷲއީ، ގަދަފަދަވަންތަ، އުގޫބާތް ގަދަފަދަވެގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","53","ذَٰلِكَ بِأَنَّ ٱللَّهَ لَمۡ يَكُ مُغَيِّرٗا نِّعۡمَةً أَنۡعَمَهَا عَلَىٰ قَوۡمٍ حَتَّىٰ يُغَيِّرُواْ مَا بِأَنفُسِهِمۡ وَأَنَّ ٱللَّهَ سَمِيعٌ عَلِيمٞ ٥٣","ذلك بأن الله لم يك مغيرا نعمة أنعمها على قوم حتى يغيروا ما بأنفسهم وأن الله سميع عليم","އެއީ ބަޔަކުމީހުންނަށް ﷲ ދެއްވާފައިވާ ނިއުމަތެއް، އެބަޔަކުގެ އަމިއްލަ ނަފްސު ތަކުގައިވާ ކަންތައް އެބަޔަކު އަމިއްލައަށް ބަދަލުކޮށްފުމަށް ދާނދެން ހަމަކަށަވަރުން، އެކަލާނގެ ބަދަލެއް ނުކުރައްވާނެއެވެ. އަދި ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","54","كَدَأۡبِ ءَالِ فِرۡعَوۡنَ وَٱلَّذِينَ مِن قَبۡلِهِمۡۚ كَذَّبُواْ بِـَٔايَٰتِ رَبِّهِمۡ فَأَهۡلَكۡنَٰهُم بِذُنُوبِهِمۡ وَأَغۡرَقۡنَآ ءَالَ فِرۡعَوۡنَۚ وَكُلّٞ كَانُواْ ظَٰلِمِينَ ٥٤","كدأب آل فرعون والذين من قبلهم كذبوا بآيات ربهم فأهلكناهم بذنوبهم وأغرقنا آل فرعون وكل كانوا ظالمين","(އެއުރެންގެ އާދަ ވީ) ފިރްޢައުނުގެ މީހުންނާއި، އެއުރެންގެ ކުރިން އުޅުނު (ނުބައި) މީހުންގެ އާދަ ފަދައިންނެވެ. އެއުރެންވެސް، އެއުރެންގެ ވެރިރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުޅައޫއެވެ. ފަހެ، އެއުރެންގެ ފާފަތަކުގެ ސަބަބުން، ތިމަންރަސްކަލާނގެ އެއުރެން ހަލާކުކުރެއްވީމެވެ. އަދި ފިރްޢައުނުގެމީހުން ޣަރަގުކުރެއްވީމެވެ. އެ އެންމެންވީ، އަނިޔާވެރިން ކަމުގައެވެ.","",""],["₈ سورة الأَنفال","55","إِنَّ شَرَّ ٱلدَّوَآبِّ عِندَ ٱللَّهِ ٱلَّذِينَ كَفَرُواْ فَهُمۡ لَا يُؤۡمِنُونَ ٥٥","إن شر الدواب عند الله الذين كفروا فهم لا يؤمنون","ހަމަކަށަވަރުން، ދިރޭތަކެތީގެ ތެރެއިން، ﷲގެ ހަޒުރަތުގައި އެންމެ ނުބައިކަން ބޮޑުބަޔަކީ، ކާފިރު ވީ މީހުންނެވެ. ފަހެ، އެއުރެން އީމާނެއް ނުވާނެތެވެ.","",""],["₈ سورة الأَنفال","56","ٱلَّذِينَ عَٰهَدتَّ مِنۡهُمۡ ثُمَّ يَنقُضُونَ عَهۡدَهُمۡ فِي كُلِّ مَرَّةٖ وَهُمۡ لَا يَتَّقُونَ ٥٦","الذين عاهدت منهم ثم ينقضون عهدهم في كل مرة وهم لا يتقون","އެއުރެންނަކީ، ކަލޭގެފާނު އެއުރެންނާ އަހުދުކުރެއްވި މީހުންނެވެ. ދެން ކޮންމެފަހަރަކު، އެއުރެން، އެއުރެންގެ އަހުދު އުވާލައެވެ. އަދި އެއުރެން (ﷲއަށް) ބިރުވެތިވާކަމުގައި ނުވެތެވެ.","",""],["₈ سورة الأَنفال","57","فَإِمَّا تَثۡقَفَنَّهُمۡ فِي ٱلۡحَرۡبِ فَشَرِّدۡ بِهِم مَّنۡ خَلۡفَهُمۡ لَعَلَّهُمۡ يَذَّكَّرُونَ ٥٧","فإما تثقفنهم في الحرب فشرد بهم من خلفهم لعلهم يذكرون","ފަހެ، ހަނގުރާމައިގައި، ކަލޭގެފާނު އެއުރެން އަތުލައްވައިފިނަމަ، އެއުރެންގެ ފަހުން އަންނާންތިބި ބަޔަކު ވަކިވަކިވެގެންދާނޭގޮތުން، އެއުރެންނަށް އަދަބު ދެއްވާށެވެ! (އެއީ) އެއުރެން ހަނދުމަކުރުމަށްޓަކައެވެ.","",""],["₈ سورة الأَنفال","58","وَإِمَّا تَخَافَنَّ مِن قَوۡمٍ خِيَانَةٗ فَٱنۢبِذۡ إِلَيۡهِمۡ عَلَىٰ سَوَآءٍۚ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلۡخَآئِنِينَ ٥٨","وإما تخافن من قوم خيانة فانبذ إليهم على سواء إن الله لا يحب الخائنين","ބަޔަކުމީހުންގެ ކިބައިން ޚިޔާނަތް ތެރިކަމެއް އަތުވެދާނެކަމަށް، ކަލޭގެފާނު ބިރުފުޅުގަންނަނަމަ (އެބަޔަކާއެކު ކޮށްފައިވާ މުޢާހަދާއެއް) އެބަޔަކުގެ މައްޗަށް އަނބުރާ ރައްދުކުރައްވާށެވެ! ހަމަހަމަވާގޮތުގެ މަތިންނެވެ. ހަމަކަށަވަރުން، ޚިޔާނަތް ތެރިންދެކެ ﷲ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["₈ سورة الأَنفال","59","وَلَا يَحۡسَبَنَّ ٱلَّذِينَ كَفَرُواْ سَبَقُوٓاْۚ إِنَّهُمۡ لَا يُعۡجِزُونَ ٥٩","ولا يحسبن الذين كفروا سبقوا إنهم لا يعجزون","(މިންޖުވެ) ކުރިއަރައިގެން ދެވޭނެކަމަށް ކާފިރުވި މީހުން ހީނުކުރާހުށިކަމެވެ! ހަމަކަށަވަރުން، އެއުރެންނަކަށް (ﷲ) ނުކުޅައްދައެއް ނުލެވޭނެތެވެ.","",""],["₈ سورة الأَنفال","60","وَأَعِدُّواْ لَهُم مَّا ٱسۡتَطَعۡتُم مِّن قُوَّةٖ وَمِن رِّبَاطِ ٱلۡخَيۡلِ تُرۡهِبُونَ بِهِۦ عَدُوَّ ٱللَّهِ وَعَدُوَّكُمۡ وَءَاخَرِينَ مِن دُونِهِمۡ لَا تَعۡلَمُونَهُمُ ٱللَّهُ يَعۡلَمُهُمۡۚ وَمَا تُنفِقُواْ مِن شَيۡءٖ فِي سَبِيلِ ٱللَّهِ يُوَفَّ إِلَيۡكُمۡ وَأَنتُمۡ لَا تُظۡلَمُونَ ٦٠","وأعدوا لهم ما استطعتم من قوة ومن رباط الخيل ترهبون به عدو الله وعدوكم وآخرين من دونهم لا تعلمونهم الله يعلمهم وما تنفقوا من شيء في سبيل الله يوف إليكم وأنتم لا تظلمون","އެއުރެންނާ ދެކޮޅަށް ތިޔަބައިމީހުންނަށް ކުޅަދާނަވީހައި ބާރެއް ތިޔަބައިމީހުން ތައްޔާރުކުރާށެވެ! އަދި އަސްތައްވެސް ބަނދެ ތައްޔާރުކުރާށެވެ! އެކަމުން ﷲގެ އަދުއްވްނާއި، ތިޔަބައިމީހުންގެ އަދުއްވްނާއި، އެއުރެންނޫން އެހެންބަޔަކު ބިރުގެންނެވުމަށްޓަކައެވެ. ތިޔަބައިމީހުންނަކަށް އެއުރެންނެއް ނޭނގެތެވެ. ﷲ، އެއުރެން ދެނެވޮޑިގެންވެތެވެ. އަދި ﷲގެ މަގުގައި ތިޔަބައިމީހުން ހޭދަކުރާ އެއްޗެއް، ތިޔަބައިމީހުންނަށް ފުރިހަމަޔަށް ލިބޭނެތެވެ. އަދި ތިޔަބައިމީހުންނަށް ބޭއިންސާފެއް ނުކުރައްވާހުށްޓެވެ.","",""],["₈ سورة الأَنفال","61","۞وَإِن جَنَحُواْ لِلسَّلۡمِ فَٱجۡنَحۡ لَهَا وَتَوَكَّلۡ عَلَى ٱللَّهِۚ إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلۡعَلِيمُ ٦١","وإن جنحوا للسلم فاجنح لها وتوكل على الله إنه هو السميع العليم","އަދި ސުލްހަ އިގެ ފަރާތަށް އެއުރެން ލެނބިލައިފިނަމަ، ކަލޭގެފާނުވެސް (އެގޮތް ގަބޫލުކުރައްވައި) އެފަރާތަށް ލެނބިވަޑައިގަންނަވާށެވެ! އަދި ﷲއަށް ވަކީލުކުރައްވާށެވެ! ހަމަކަށަވަރުން، އެކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","62","وَإِن يُرِيدُوٓاْ أَن يَخۡدَعُوكَ فَإِنَّ حَسۡبَكَ ٱللَّهُۚ هُوَ ٱلَّذِيٓ أَيَّدَكَ بِنَصۡرِهِۦ وَبِٱلۡمُؤۡمِنِينَ ٦٢","وإن يريدوا أن يخدعوك فإن حسبك الله هو الذي أيدك بنصره وبالمؤمنين","އަދި ކަލޭގެފާނަށް ކެހިދިނުމަށް އެއުރެން ގަސްދުކުރާނަމަ، ފަހެ، ހަމަކަށަވަރުން، ކަލޭގެފާނަށް ﷲ ފުދެތެވެ. އެކަލާނގެއީ، އެކަލާނގެ ނަސްރާއި، މުއުމިނުން މެދުވެރިކުރައްވައިގެން، ކަލޭގެފާނަށް ގަދަކަންދެއްވި ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","63","وَأَلَّفَ بَيۡنَ قُلُوبِهِمۡۚ لَوۡ أَنفَقۡتَ مَا فِي ٱلۡأَرۡضِ جَمِيعٗا مَّآ أَلَّفۡتَ بَيۡنَ قُلُوبِهِمۡ وَلَٰكِنَّ ٱللَّهَ أَلَّفَ بَيۡنَهُمۡۚ إِنَّهُۥ عَزِيزٌ حَكِيمٞ ٦٣","وألف بين قلوبهم لو أنفقت ما في الأرض جميعا ما ألفت بين قلوبهم ولكن الله ألف بينهم إنه عزيز حكيم","އަދި އެކަލާނގެ އެއުރެންގެ ހިތްތައް (އެބަހީ: މުއުމިނުންގެ ހިތްތައް) އެކުވެރި ކުރެއްވިއެވެ. ކަލޭގެފާނު ބިމުގައިވާ ހުރިހާ އެއްޗެއް ހޭދަކުރެއްވިޔަސް އެއުރެންގެ ހިތްތައް އެކުވެރިއެއް ނުކުރެއްވުނީހެވެ. އެހެނެއްކަމަކު، ﷲ، އެއުރެން އެކުވެރި ކުރެއްވިއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","64","يَـٰٓأَيُّهَا ٱلنَّبِيُّ حَسۡبُكَ ٱللَّهُ وَمَنِ ٱتَّبَعَكَ مِنَ ٱلۡمُؤۡمِنِينَ ٦٤","يا أيها النبي حسبك الله ومن اتبعك من المؤمنين","އޭ ނަބިއްޔާއެވެ! ކަލޭގެފާނަށް ﷲ ފުދެތެވެ. އަދި މުއުމިނުންގެ ތެރެއިން ކަލޭގެފާނަށް ތަބާ ވީ މީހަކަށްވެސް މެއެވެ.","",""],["₈ سورة الأَنفال","65","يَـٰٓأَيُّهَا ٱلنَّبِيُّ حَرِّضِ ٱلۡمُؤۡمِنِينَ عَلَى ٱلۡقِتَالِۚ إِن يَكُن مِّنكُمۡ عِشۡرُونَ صَٰبِرُونَ يَغۡلِبُواْ مِاْئَتَيۡنِۚ وَإِن يَكُن مِّنكُم مِّاْئَةٞ يَغۡلِبُوٓاْ أَلۡفٗا مِّنَ ٱلَّذِينَ كَفَرُواْ بِأَنَّهُمۡ قَوۡمٞ لَّا يَفۡقَهُونَ ٦٥","يا أيها النبي حرض المؤمنين على القتال إن يكن منكم عشرون صابرون يغلبوا مائتين وإن يكن منكم مائة يغلبوا ألفا من الذين كفروا بأنهم قوم لا يفقهون","އޭ ނަބިއްޔާއެވެ! (ދީންގެ ދިފާޢުގައި) ހަނގުރާމަކުރުމަށް މުއުމިނު ތަކުންނަށް ކަލޭގެފާނު ހިތްވަރުދެއްވާށެވެ! ތިޔަބައިމީހުންގެ ތެރެއިން ކެތްތެރި ވިހި މީހުން ތިބިނަމަ (ކާފިރުންގެ) ދުއިސައްތަ މީހުންގެ މައްޗަށް ގަދަވެގަނެވޭނެތެވެ. އަދި ތިޔަބައިމީހުންކުރެ، ސަތޭކަމީހުން ތިބިނަމަ، ކާފިރުވި މީހުންގެ ތެރެއިން އެއްހާސްމީހުންގެ މައްޗަށް ގަދަވެގަނެވޭނެތެވެ. އެހެނީ އެއުރެންނަކީ ނުވިސްނޭ ބަޔެކެވެ.","",""],["₈ سورة الأَنفال","66","ٱلۡـَٰٔنَ خَفَّفَ ٱللَّهُ عَنكُمۡ وَعَلِمَ أَنَّ فِيكُمۡ ضَعۡفٗاۚ فَإِن يَكُن مِّنكُم مِّاْئَةٞ صَابِرَةٞ يَغۡلِبُواْ مِاْئَتَيۡنِۚ وَإِن يَكُن مِّنكُمۡ أَلۡفٞ يَغۡلِبُوٓاْ أَلۡفَيۡنِ بِإِذۡنِ ٱللَّهِۗ وَٱللَّهُ مَعَ ٱلصَّـٰبِرِينَ ٦٦","الآن خفف الله عنكم وعلم أن فيكم ضعفا فإن يكن منكم مائة صابرة يغلبوا مائتين وإن يكن منكم ألف يغلبوا ألفين بإذن الله والله مع الصابرين","މިހާރު، ﷲ ތިޔަބައިމީހުންގެ ކިބައިން ލުއިކުރައްވައިފިއެވެ. އަދި ތިޔަބައިމީހުންގެ ކިބައިގައި ބަލިކަށިކަމެއްވާކަން އެކަލާނގެ ދެނެވޮޑިގެންވެއެވެ. ފަހެ، ތިޔަބައިމީހުންކުރެ، ކެތްތެރި ސަތޭކަ މީހުން ތިބިނަމަ، (އެއުރެންގެ) ދުއިސައްތަ މީހުންގެ މައްޗަށް ގަދަވެގަނެވޭނެތެވެ. އަދި ތިޔަބައިމީހުންކުރެ އެއްހާސް މީހުން ތިބިނަމަ (އެއުރެންގެ) ދެހާސް މީހުންގެ މައްޗަށް ގަދަވެގަނެވޭނެތެވެ. ﷲގެ އިޒުނަ ޔާ އެކުގައެވެ. ﷲ ވޮޑިގެންވަނީ، ކެތްތެރިންނާ އެކުގައެވެ.","",""],["₈ سورة الأَنفال","67","مَا كَانَ لِنَبِيٍّ أَن يَكُونَ لَهُۥٓ أَسۡرَىٰ حَتَّىٰ يُثۡخِنَ فِي ٱلۡأَرۡضِۚ تُرِيدُونَ عَرَضَ ٱلدُّنۡيَا وَٱللَّهُ يُرِيدُ ٱلۡأٓخِرَةَۗ وَٱللَّهُ عَزِيزٌ حَكِيمٞ ٦٧","ما كان لنبي أن يكون له أسرى حتى يثخن في الأرض تريدون عرض الدنيا والله يريد الآخرة والله عزيز حكيم","(ހަނގުރާމައިގެ) ބިމުގައި (އަދުއްވުންގެ މެދުގައި) ގަތުލު ގިނަވެއްޖައުމަށް ދާނދެން (އެބަހީ: މުސްލިމުން ގަދަވެ ގަތުލު ވެވޭ އަދުއްވުންގެ އަދަދު ގިނަވެ، ހަނގުރާމައަށް ނުކުޅެދިއްޖައުމަށްދާނދެން) ހަނގުރާމައިގައި މީހުންހިފައި ހައްޔަރުކުރުމަކީ، އެއްވެސް ނަބިއްޔަކަށް އޮތްކަމެއްނޫނެވެ. ދުނިޔޭގެ މުދަލަށް ތިޔަބައިމީހުން އެދެމުއެވެ. ﷲ އިރާދަކުރައްވަނީ، އާޚިރަތެވެ. ﷲއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","68","لَّوۡلَا كِتَٰبٞ مِّنَ ٱللَّهِ سَبَقَ لَمَسَّكُمۡ فِيمَآ أَخَذۡتُمۡ عَذَابٌ عَظِيمٞ ٦٨","لولا كتاب من الله سبق لمسكم فيما أخذتم عذاب عظيم","ﷲ ކަނޑައަޅުއްވައި ލިޔުއްވާފައިވާ ހުކުމެއް އިސްވެގޮސްފައިނުވާނަމަ، ތިޔަބައިމީހުން ހިފިތަކެއްޗާމެދު ތިޔަބައިމީހުންނަށް ބޮޑުވެގެންވާ އަޒާބެއް އައިސް ޖެހިއްޖައީހެވެ.","",""],["₈ سورة الأَنفال","69","فَكُلُواْ مِمَّا غَنِمۡتُمۡ حَلَٰلٗا طَيِّبٗاۚ وَٱتَّقُواْ ٱللَّهَۚ إِنَّ ٱللَّهَ غَفُورٞ رَّحِيمٞ ٦٩","فكلوا مما غنمتم حلالا طيبا واتقوا الله إن الله غفور رحيم","ފަހެ، ތިޔަބައިމީހުންނަށް ޣަނީމާގެ ގޮތުން ލިބިފައިވާ ތަކެތި ހަލާލު ރަނގަޅު ތަކެތީގެ ގޮތުގައި ކައިއުޅޭށެވެ! އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","70","يَـٰٓأَيُّهَا ٱلنَّبِيُّ قُل لِّمَن فِيٓ أَيۡدِيكُم مِّنَ ٱلۡأَسۡرَىٰٓ إِن يَعۡلَمِ ٱللَّهُ فِي قُلُوبِكُمۡ خَيۡرٗا يُؤۡتِكُمۡ خَيۡرٗا مِّمَّآ أُخِذَ مِنكُمۡ وَيَغۡفِرۡ لَكُمۡۚ وَٱللَّهُ غَفُورٞ رَّحِيمٞ ٧٠","يا أيها النبي قل لمن في أيديكم من الأسرى إن يعلم الله في قلوبكم خيرا يؤتكم خيرا مما أخذ منكم ويغفر لكم والله غفور رحيم","އޭ ނަބިއްޔާއެވެ! ތިޔަބައިމީހުންގެ އަތްދަށުގައި (ހަނގުރާމައިގައި) ހައްޔަރުވެފައިވާ މީހުންނަށް ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންގެ ހިތްތަކުގައި އެއްވެސް ހެޔޮކަމެއްވާކަން ﷲ ދެނެވޮޑިގެންވާނަމަ، ތިޔަބައިމީހުން އަތުން އަތުލެއްވި ތަކެއްޗަށްވުރެން ރަނގަޅު ތަކެތި ތިޔަބައިމީހުންނަށް ދެއްވާނެތެވެ. އަދި ތިޔަބައިމީހުންނަށް ފާފަފުއްސަވާނެތެވެ. އަދި ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","71","وَإِن يُرِيدُواْ خِيَانَتَكَ فَقَدۡ خَانُواْ ٱللَّهَ مِن قَبۡلُ فَأَمۡكَنَ مِنۡهُمۡۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌ ٧١","وإن يريدوا خيانتك فقد خانوا الله من قبل فأمكن منهم والله عليم حكيم","އަދި އެއުރެން އެދެނީ ކަލޭގެފާނަށް ޚިޔާނަތް ތެރިވުން ކަމުގައިވާނަމަ، (ދަންނާށެވެ!) ފަހެ، އޭގެކުރިން ހަމަކަށަވަރުން، އެއުރެން ﷲއަށް ޚިޔާނަތް ތެރިވިއެވެ. ދެން އެކަލާނގެ އެއުރެންގެ މައްޗަށް ކަލޭގެފާނު ބާރުވެރި ކުރެއްވިއެވެ. އަދި ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","72","إِنَّ ٱلَّذِينَ ءَامَنُواْ وَهَاجَرُواْ وَجَٰهَدُواْ بِأَمۡوَٰلِهِمۡ وَأَنفُسِهِمۡ فِي سَبِيلِ ٱللَّهِ وَٱلَّذِينَ ءَاوَواْ وَّنَصَرُوٓاْ أُوْلَـٰٓئِكَ بَعۡضُهُمۡ أَوۡلِيَآءُ بَعۡضٖۚ وَٱلَّذِينَ ءَامَنُواْ وَلَمۡ يُهَاجِرُواْ مَا لَكُم مِّن وَلَٰيَتِهِم مِّن شَيۡءٍ حَتَّىٰ يُهَاجِرُواْۚ وَإِنِ ٱسۡتَنصَرُوكُمۡ فِي ٱلدِّينِ فَعَلَيۡكُمُ ٱلنَّصۡرُ إِلَّا عَلَىٰ قَوۡمِۭ بَيۡنَكُمۡ وَبَيۡنَهُم مِّيثَٰقٞۗ وَٱللَّهُ بِمَا تَعۡمَلُونَ بَصِيرٞ ٧٢","إن الذين آمنوا وهاجروا وجاهدوا بأموالهم وأنفسهم في سبيل الله والذين آووا ونصروا أولئك بعضهم أولياء بعض والذين آمنوا ولم يهاجروا ما لكم من ولايتهم من شيء حتى يهاجروا وإن استنصروكم في الدين فعليكم النصر إلا على قوم بينكم وبينهم ميثاق والله بما تعملون بصير","ހަމަކަށަވަރުން، އީމާންވެ ހިޖުރަ ކޮށް އެއުރެންގެ މުދާތަކާއި، ނަފްސު ތަކުން ﷲގެ މަގުގައި ޖިހާދު ކޮށް އުޅުނު މީހުންނާއި، (އެއުރެންނަށް) ހިޔާވަހިކަންދީ، ނަސްރު ދިންމީހުން (ދަންނާށެވެ!) އެއުރެންގެ އެއްބަޔަކީ، އަނެއްބަޔެއްގެ އެހީތެރިންނެވެ. އަދި އީމާންވެ ހިޖުރަ ނުކޮށްތިބި މީހުން (ދަންނާށެވެ!) އެއުރެން ހިޖުރަ ކޮށްފުމަށްދާނދެން، އެއުރެންނަށް އެހީތެރިވުމުގެ އެއްވެސްކަމެއް ތިޔަބައިމީހުންނަކަށް ނެތެވެ. އަދި ދީންގެ ނަމުގައި އެއުރެން ތިޔަބައިމީހުންގެ އެހީއަށް އެދިއްޖެނަމަ، އެއުރެންނަށް ނަސްރު ދިނުން ތިޔަބައިމީހުންގެ މައްޗަށް ހުށްޓެވެ. އެއުރެންނާއި، ތިޔަބައިމީހުންނާ ދެމެދުގައި މުޢާހަދާއެއް ކޮށްފައިވާ ގައުމަކާ ދެކޮޅަށް މެނުވީއެވެ. ﷲއީ، ތިޔަބައިމީހުން ކުރާ ކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₈ سورة الأَنفال","73","وَٱلَّذِينَ كَفَرُواْ بَعۡضُهُمۡ أَوۡلِيَآءُ بَعۡضٍۚ إِلَّا تَفۡعَلُوهُ تَكُن فِتۡنَةٞ فِي ٱلۡأَرۡضِ وَفَسَادٞ كَبِيرٞ ٧٣","والذين كفروا بعضهم أولياء بعض إلا تفعلوه تكن فتنة في الأرض وفساد كبير","ކާފިރުވި މީހުން (ދަންނާށެވެ! (އެއުރެންގެ އެއްބަޔަކީ، އަނެއްބަޔެއްގެ އެހީތެރިންނެވެ. ތިޔަބައިމީހުން އެކަންނުކުރާނަމަ) އެބަހީ: ތިޔަބައިމީހުން އެއްބަޔަކު އަނެއްބަޔަކަށް ނަސްރު ދީ އެހީވެ ނޫޅޭނަމަ) ބިމުގައި ފިތުނަވެރިކަމާއި، ބޮޑުވެގެންވާ ފަސާދަވެރިކަން އުފެދިދާނެތެވެ.","",""],["₈ سورة الأَنفال","74","وَٱلَّذِينَ ءَامَنُواْ وَهَاجَرُواْ وَجَٰهَدُواْ فِي سَبِيلِ ٱللَّهِ وَٱلَّذِينَ ءَاوَواْ وَّنَصَرُوٓاْ أُوْلَـٰٓئِكَ هُمُ ٱلۡمُؤۡمِنُونَ حَقّٗاۚ لَّهُم مَّغۡفِرَةٞ وَرِزۡقٞ كَرِيمٞ ٧٤","والذين آمنوا وهاجروا وجاهدوا في سبيل الله والذين آووا ونصروا أولئك هم المؤمنون حقا لهم مغفرة ورزق كريم","އަދި އީމާންވެ ހިޖުރަ ކޮށް، ﷲގެ މަގުގައި ޖިހާދު ކޮށްއުޅުނު މީހުންނާއި (އެއުރެންނަށް) ހިޔާވަހިކަންދީ ނަސްރު ދިން މީހުން (ދަންނާށެވެ!) ހަގީގަތުގައި މުއުމިނުންނަކީ، ހަމަ އެއުރެންނެވެ. އެއުރެންނަށް ފާފަފުއްސެވުމާއި ދީލަތިވެގެންވާ ރިޒްގު ހުށްޓެވެ.","",""],["₈ سورة الأَنفال","75","وَٱلَّذِينَ ءَامَنُواْ مِنۢ بَعۡدُ وَهَاجَرُواْ وَجَٰهَدُواْ مَعَكُمۡ فَأُوْلَـٰٓئِكَ مِنكُمۡۚ وَأُوْلُواْ ٱلۡأَرۡحَامِ بَعۡضُهُمۡ أَوۡلَىٰ بِبَعۡضٖ فِي كِتَٰبِ ٱللَّهِۚ إِنَّ ٱللَّهَ بِكُلِّ شَيۡءٍ عَلِيمُۢ ٧٥","والذين آمنوا من بعد وهاجروا وجاهدوا معكم فأولئك منكم وأولو الأرحام بعضهم أولى ببعض في كتاب الله إن الله بكل شيء عليم","އަދި އޭގެފަހުން އީމާންވެ، ހިޖުރަ ކޮށް، ތިޔަބައިމީހުންނާއެކުގައި ޖިހާދު ކޮށް އުޅުނުމީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެންވަނީ ތިޔަބައިމީހުންގެ ތެރެއިންނެވެ. އަދި ﷲގެ ފޮތުގައި ކަނޑައަޅުއްވާފައިވާގޮތުގައި، ގާތްތިމާގެ މީހުން އޭގެ އެއްބަޔަކު އަނެއްބަޔަކާ އައުލާ ކަން ބޮޑެވެ. ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","1","بَرَآءَةٞ مِّنَ ٱللَّهِ وَرَسُولِهِۦٓ إِلَى ٱلَّذِينَ عَٰهَدتُّم مِّنَ ٱلۡمُشۡرِكِينَ ١","براءة من الله ورسوله إلى الذين عاهدتم من المشركين","(މިއީ) މުޝްރިކުންގެ ތެރެއިން ތިޔަބައިމީހުން މުޢާހަދާއެއްކޮށް އެ މުޢާހަދާ އުވާލާފައިވާ ބަޔަކުގެ ކިބައިން ﷲއާއި، އެކަލާނގެ ރަސޫލާ ބަރީއަވެގެންވާކަމުގެ އެންގެވުމެކެވެ.","",""],["₉ سورة التوبة","2","فَسِيحُواْ فِي ٱلۡأَرۡضِ أَرۡبَعَةَ أَشۡهُرٖ وَٱعۡلَمُوٓاْ أَنَّكُمۡ غَيۡرُ مُعۡجِزِي ٱللَّهِ وَأَنَّ ٱللَّهَ مُخۡزِي ٱلۡكَٰفِرِينَ ٢","فسيحوا في الأرض أربعة أشهر واعلموا أنكم غير معجزي الله وأن الله مخزي الكافرين","ފަހެ، ތިޔަބައިމީހުން (އެބަހީ: މުޝްރިކުން) ހަތަރު މަސްވަންދެން ބިމުގައި ހިނގާބިނގާ އުޅޭށެވެ! އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށް ﷲ، ނުކުޅައްދައި ނުލެވޭނެކަމާއި، ހަމަކަށަވަރުން ﷲ، ކާފިރު ތަކުން ދެރަކޮށްލައްވާހުށިކަން، ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₉ سورة التوبة","3","وَأَذَٰنٞ مِّنَ ٱللَّهِ وَرَسُولِهِۦٓ إِلَى ٱلنَّاسِ يَوۡمَ ٱلۡحَجِّ ٱلۡأَكۡبَرِ أَنَّ ٱللَّهَ بَرِيٓءٞ مِّنَ ٱلۡمُشۡرِكِينَ وَرَسُولُهُۥۚ فَإِن تُبۡتُمۡ فَهُوَ خَيۡرٞ لَّكُمۡۖ وَإِن تَوَلَّيۡتُمۡ فَٱعۡلَمُوٓاْ أَنَّكُمۡ غَيۡرُ مُعۡجِزِي ٱللَّهِۗ وَبَشِّرِ ٱلَّذِينَ كَفَرُواْ بِعَذَابٍ أَلِيمٍ ٣","وأذان من الله ورسوله إلى الناس يوم الحج الأكبر أن الله بريء من المشركين ورسوله فإن تبتم فهو خير لكم وإن توليتم فاعلموا أنكم غير معجزي الله وبشر الذين كفروا بعذاب أليم","އަދި މިއީ ބޮޑުވެގެންވާ ހައްޖުގެ ދުވަހު، ﷲއާއި، އެކަލާނގެ ރަސޫލާގެ ކިބައިން، މީސްތަކުންނަށް އޮތް އެންގެވުމެކެވެ. (މިއަދަށްފަހު) ހަމަކަށަވަރުން، ﷲއާއި، އެކަލާނގެ ރަސޫލާ ވަނީ، މުޝްރިކުންގެ ކިބައިން ބަރީއަވެގެންނެވެ. ފަހެ، ތިޔަބައިމީހުން (މުޝްރިކުން) ތައުބާ ވެއްޖެނަމަ (ދަންނާށެވެ!) ފަހެ، އެގޮތް ތިޔަބައިމީހުންނަށް ހެޔޮކަން ބޮޑެވެ. އަދި ތިޔަބައިމީހުން ފުރަގަސްދީފިނަމަ، ފަހެ، ތިޔަބައިމީހުންނަށް ﷲ ނުކުޅައްދައެއް ނުލެވޭނެކަން ތިޔަބައިމީހުން ދަންނާށެވެ! ކާފިރުވި މީހުންނަށް ވޭންދެނިވި އަޒާބު ހުރިކަމުގެ ޚަބަރު، ކަލޭގެފާނު ދެއްވާށެވެ!","",""],["₉ سورة التوبة","4","إِلَّا ٱلَّذِينَ عَٰهَدتُّم مِّنَ ٱلۡمُشۡرِكِينَ ثُمَّ لَمۡ يَنقُصُوكُمۡ شَيۡـٔٗا وَلَمۡ يُظَٰهِرُواْ عَلَيۡكُمۡ أَحَدٗا فَأَتِمُّوٓاْ إِلَيۡهِمۡ عَهۡدَهُمۡ إِلَىٰ مُدَّتِهِمۡۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلۡمُتَّقِينَ ٤","إلا الذين عاهدتم من المشركين ثم لم ينقصوكم شيئا ولم يظاهروا عليكم أحدا فأتموا إليهم عهدهم إلى مدتهم إن الله يحب المتقين","މުޝްރިކުންގެ ތެރެއިން އެބަޔަކާ، ތިޔަބައިމީހުން މުޢާހަދާ ކޮށްފައިވާ، އަދި އެއުރެން (އެ މުޢާހަދާއާމެދު) ތިޔަބައިމީހުންނަށް އެއްވެސްކަމެއް އުނިކޮށްފައިނުވާ އަދި ތިޔަބައިމީހުންނާ ދެކޮޅަށް އެއްވެސްމީހަކަށް އެހީވެ، ވާގިދީފައިނުވާ މީހުން މެނުވީއެވެ. ފަހެ، ތިޔަބައިމީހުން އެއުރެންގެ މުއްދަތު ހަމަވަންދެން އެއުރެންގެ އަހުދު ފުރިހަމަކުރާށެވެ! ހަމަކަށަވަރުން، ތަގުވާވެރިންދެކެ، ﷲ ލޯބިވެވޮޑިގެންވެއެވެ.","",""],["₉ سورة التوبة","5","فَإِذَا ٱنسَلَخَ ٱلۡأَشۡهُرُ ٱلۡحُرُمُ فَٱقۡتُلُواْ ٱلۡمُشۡرِكِينَ حَيۡثُ وَجَدتُّمُوهُمۡ وَخُذُوهُمۡ وَٱحۡصُرُوهُمۡ وَٱقۡعُدُواْ لَهُمۡ كُلَّ مَرۡصَدٖۚ فَإِن تَابُواْ وَأَقَامُواْ ٱلصَّلَوٰةَ وَءَاتَوُاْ ٱلزَّكَوٰةَ فَخَلُّواْ سَبِيلَهُمۡۚ إِنَّ ٱللَّهَ غَفُورٞ رَّحِيمٞ ٥","فإذا انسلخ الأشهر الحرم فاقتلوا المشركين حيث وجدتموهم وخذوهم واحصروهم واقعدوا لهم كل مرصد فإن تابوا وأقاموا الصلاة وآتوا الزكاة فخلوا سبيلهم إن الله غفور رحيم","ހުރުމަތް ތެރި މައްސަރުތައް ވޭތުވުމުން، ފަހެ، ތިޔަބައިމީހުންނަށް މުޝްރިކުން ފެނުނު ކޮންމެ ތަނަކުން، ތިޔަބައިމީހުން އެއުރެން ގަތުލުކުރާށެވެ! އަދި ތިޔަބައިމީހުން އެއުރެން ހިފާށެވެ! އަދި އެއުރެން ޙިޞާރުކުރާށެވެ! އަދި (އެއުރެން އަތުލައިގަނެވޭނެ) ކޮންމެތަނެއްގައި އެއުރެން އަތުލައިގަތުމަށްޓަކައި، ހުޝިޔާރުވެ ފިލައިތިބޭށެވެ! ފަހެ، އެއުރެން ތައުބާވެ، ނަމާދު ގާއިމު ކޮށް، ޒަކާތް ދީ އުޅެފިނަމަ، ދެން އެއުރެން މިނިވަންކަމާއެކު ދޫކޮށްލާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","6","وَإِنۡ أَحَدٞ مِّنَ ٱلۡمُشۡرِكِينَ ٱسۡتَجَارَكَ فَأَجِرۡهُ حَتَّىٰ يَسۡمَعَ كَلَٰمَ ٱللَّهِ ثُمَّ أَبۡلِغۡهُ مَأۡمَنَهُۥۚ ذَٰلِكَ بِأَنَّهُمۡ قَوۡمٞ لَّا يَعۡلَمُونَ ٦","وإن أحد من المشركين استجارك فأجره حتى يسمع كلام الله ثم أبلغه مأمنه ذلك بأنهم قوم لا يعلمون","އަދި މުޝްރިކުންގެ ތެރެއިން އެއްވެސްމީހަކު، ކަލޭގެފާނުގެ އަރިހުން ރައްކާތެރިކަމަކަށް އެދިއްޖެނަމަ، ފަހެ، އެމީހަކު ﷲގެ ކަލާމްފުޅު އަހައިފުމަށްދާނދެން އެމީހަކަށް ރައްކާތެރިކަން ދެއްވާށެވެ! ދެންފަހެ، އަމާންކަން ލިބިގެންވާ ތަނަކާ ހަމަޔަށް އެމީހަކު ގެންގޮސްދެއްވާށެވެ! އެއީ ހަމަކަށަވަރުންވެސް، އެއުރެންނީ ނުދަންނަ ބަޔެކެވެ.","",""],["₉ سورة التوبة","7","كَيۡفَ يَكُونُ لِلۡمُشۡرِكِينَ عَهۡدٌ عِندَ ٱللَّهِ وَعِندَ رَسُولِهِۦٓ إِلَّا ٱلَّذِينَ عَٰهَدتُّمۡ عِندَ ٱلۡمَسۡجِدِ ٱلۡحَرَامِۖ فَمَا ٱسۡتَقَٰمُواْ لَكُمۡ فَٱسۡتَقِيمُواْ لَهُمۡۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلۡمُتَّقِينَ ٧","كيف يكون للمشركين عهد عند الله وعند رسوله إلا الذين عاهدتم عند المسجد الحرام فما استقاموا لكم فاستقيموا لهم إن الله يحب المتقين","ﷲގެ ހަޒުރަތު ގައްޔާއި، އެކަލާނގެ ރަސޫލާގެ އަރިހުގައި، މުޝްރިކުންނަށް އަހުދެއް އޮންނާނީ، ކޮންފަދައަކުން ހެއްޔެވެ؟ ހުރުމަތް ތެރި މިސްކިތުގެ ކައިރީގައި ތިޔަބައިމީހުން އެބަޔަކާ އަހުދުކުރި މީހުންނަށް މެނުވީއެވެ. ފަހެ، އެއުރެން ތިޔަބައިމީހުންނަށް ސީދާވެގެންތިބިހާ ހިނދަކު ތިޔަބައިމީހުންވެސް އެއުރެންނަށް ސީދާވާށެވެ! ހަމަކަށަވަރުން، ތަގުވާވެރިންދެކެ ﷲ ލޯބިވެވޮޑިގެންވެއެވެ.","",""],["₉ سورة التوبة","8","كَيۡفَ وَإِن يَظۡهَرُواْ عَلَيۡكُمۡ لَا يَرۡقُبُواْ فِيكُمۡ إِلّٗا وَلَا ذِمَّةٗۚ يُرۡضُونَكُم بِأَفۡوَٰهِهِمۡ وَتَأۡبَىٰ قُلُوبُهُمۡ وَأَكۡثَرُهُمۡ فَٰسِقُونَ ٨","كيف وإن يظهروا عليكم لا يرقبوا فيكم إلا ولا ذمة يرضونكم بأفواههم وتأبى قلوبهم وأكثرهم فاسقون","(އެއުރެންނަށް އެފަދަ އަހުދެއް އޮންނާނީ) ކިހިނަކުންހެއްޔެވެ؟ އެހެނީ ތިޔަބައިމީހުންގެ މައްޗަށް އެއުރެން ގަދަވެގެންފިނަމަ، ގާތްތިމާގެ ކަމުގެ ގުޅުމަކަށްވެސް، އަދި އަހުދަކަށްވެސް، ތިޔަބައިމީހުންނާމެދު އެއުރެން ނުބަލާނެތެވެ. އެއުރެންގެ އަނގައިން ތިޔަބައިމީހުން ރުއްސާނެތެވެ. އެއުރެންގެ ހިތްތައް ނުރުހިގެންވާ ޙާލު ގައެވެ. އޭގެތެރެއިން ގިނަމީހުންނީ، ފާސިގުންނެވެ.","",""],["₉ سورة التوبة","9","ٱشۡتَرَوۡاْ بِـَٔايَٰتِ ٱللَّهِ ثَمَنٗا قَلِيلٗا فَصَدُّواْ عَن سَبِيلِهِۦٓۚ إِنَّهُمۡ سَآءَ مَا كَانُواْ يَعۡمَلُونَ ٩","اشتروا بآيات الله ثمنا قليلا فصدوا عن سبيله إنهم ساء ما كانوا يعملون","އެއުރެން ﷲގެ އާޔަތްތަކަށް ކުޑަ އަގެއް ގަތެވެ. ފަހެ، އެއުރެން އެކަލާނގެ މަގުން (މީސްތަކުން) އެއްކިބާކުޅައެވެ. ހަމަކަށަވަރުން، އެއުރެން ކޮށްއުޅުނު ކަންތައް ހާދަހާ ނުބައިވެގެންވެއެވެ.","",""],["₉ سورة التوبة","10","لَا يَرۡقُبُونَ فِي مُؤۡمِنٍ إِلّٗا وَلَا ذِمَّةٗۚ وَأُوْلَـٰٓئِكَ هُمُ ٱلۡمُعۡتَدُونَ ١٠","لا يرقبون في مؤمن إلا ولا ذمة وأولئك هم المعتدون","ގާތްތިމާގެ ކަމުގެ ގުޅުމަކަށްވެސް، އަދި އަހުދަކަށްވެސް، އެއުރެން މުއުމިނަކާމެދު ނުބަލާނެތެވެ. އަދި އެއުރެންނީ، ހަމަ، ހައްދުފަހަނަޅައިދާ މީހުންނެވެ.","",""],["₉ سورة التوبة","11","فَإِن تَابُواْ وَأَقَامُواْ ٱلصَّلَوٰةَ وَءَاتَوُاْ ٱلزَّكَوٰةَ فَإِخۡوَٰنُكُمۡ فِي ٱلدِّينِۗ وَنُفَصِّلُ ٱلۡأٓيَٰتِ لِقَوۡمٖ يَعۡلَمُونَ ١١","فإن تابوا وأقاموا الصلاة وآتوا الزكاة فإخوانكم في الدين ونفصل الآيات لقوم يعلمون","ފަހެ، އެއުރެން ތައުބާވެ، ނަމާދު ގާއިމު ކޮށް، ޒަކާތް ދީފިނަމަ، ފަހެ، އެއުރެންނަކީ، ދީންގައި ތިޔަބައިމީހުންގެ އަޚުންނެވެ. އެނގޭބަޔަކަށް ތިމަންރަސްކަލާނގެ އާޔަތްތައް ތަފްޞީލު ކޮށްދެއްވަމެވެ.","",""],["₉ سورة التوبة","12","وَإِن نَّكَثُوٓاْ أَيۡمَٰنَهُم مِّنۢ بَعۡدِ عَهۡدِهِمۡ وَطَعَنُواْ فِي دِينِكُمۡ فَقَٰتِلُوٓاْ أَئِمَّةَ ٱلۡكُفۡرِ إِنَّهُمۡ لَآ أَيۡمَٰنَ لَهُمۡ لَعَلَّهُمۡ يَنتَهُونَ ١٢","وإن نكثوا أيمانهم من بعد عهدهم وطعنوا في دينكم فقاتلوا أئمة الكفر إنهم لا أيمان لهم لعلهم ينتهون","އަދި އެއުރެން އަހުދުކުރުމަށްފަހު، އެއުރެންގެ ހުވާތައް އުވާލައި، އަދި ތިޔަބައިމީހުންގެ ދީނަށް އައިބު ބަސް ބުނެއުޅެނީނަމަ، ތިޔަބައިމީހުން ކާފިރުކަމުގެ ބޮޑުންނާ ހަނގުރާމަކުރާށެވެ! ހަމަކަށަވަރުން، ހުވަޔަކީ، އެއުރެންނަށް އެއްވެސް އެއްޗެއްނޫނެވެ. (ހަނގުރާމަ ކުރަންވީ) އެއުރެން އެކަންތައް ހުއްޓާލާތޯއެވެ.","",""],["₉ سورة التوبة","13","أَلَا تُقَٰتِلُونَ قَوۡمٗا نَّكَثُوٓاْ أَيۡمَٰنَهُمۡ وَهَمُّواْ بِإِخۡرَاجِ ٱلرَّسُولِ وَهُم بَدَءُوكُمۡ أَوَّلَ مَرَّةٍۚ أَتَخۡشَوۡنَهُمۡۚ فَٱللَّهُ أَحَقُّ أَن تَخۡشَوۡهُ إِن كُنتُم مُّؤۡمِنِينَ ١٣","ألا تقاتلون قوما نكثوا أيمانهم وهموا بإخراج الرسول وهم بدءوكم أول مرة أتخشونهم فالله أحق أن تخشوه إن كنتم مؤمنين","އެއުރެންގެ ހުވާތައް އުވާލައި، ރަސޫލާ (ރަށުން) ބޭރުކޮށްލުމަށް ރޭވި ބަޔަކާ ތިޔަބައިމީހުން ހަނގުރާމަ ނުކުރާންވީ ކީއްވެގެންހެއްޔެވެ؟ ފުރަތަމަ ތިޔަބައިމީހުންނަށް ހަމަލާ ދިނީ އެއުރެންނެވެ. ތިޔަބައިމީހުން، އެއުރެންދެކެ ބިރުގަންނަނީ ހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުން މުއުމިނުން ކަމުގައިވާނަމަ، ތިޔަބައިމީހުން ބިރުވެތިވުން ހައްގު ކަން ބޮޑީ، ﷲއަށެވެ.","",""],["₉ سورة التوبة","14","قَٰتِلُوهُمۡ يُعَذِّبۡهُمُ ٱللَّهُ بِأَيۡدِيكُمۡ وَيُخۡزِهِمۡ وَيَنصُرۡكُمۡ عَلَيۡهِمۡ وَيَشۡفِ صُدُورَ قَوۡمٖ مُّؤۡمِنِينَ ١٤","قاتلوهم يعذبهم الله بأيديكم ويخزهم وينصركم عليهم ويشف صدور قوم مؤمنين","ތިޔަބައިމީހުން އެއުރެންނާ ހަނގުރާމަކުރާ ހުށިކަމެވެ! އޭރުން ﷲއެއުރެންނަށް ތިޔަބައިމީހުންގެ އަތްތަކުން އަޒާބު ދެއްވާނެތެވެ. އަދި އެއުރެން ނިކަމެތި ކޮށްލައްވާނެތެވެ. އަދި ތިޔަބައިމީހުންނަށް، އެއުރެންގެ މައްޗަށް ނަސްރު ދެއްވާނެތެވެ. އަދި މުއުމިނު ބަޔެއްގެ ހިތްތަކަށް ޝިފާ ދެއްވާނެތެވެ.","",""],["₉ سورة التوبة","15","وَيُذۡهِبۡ غَيۡظَ قُلُوبِهِمۡۗ وَيَتُوبُ ٱللَّهُ عَلَىٰ مَن يَشَآءُۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌ ١٥","ويذهب غيظ قلوبهم ويتوب الله على من يشاء والله عليم حكيم","އަދި އެއުރެންގެ (އެބަހީ: މުއުމިނުންގެ) ހިތްތަކުގައިވާ ރުޅިވެރިކަން ފިއްލަވާނެތެވެ. ﷲ އިރާދަކުރައްވާ ބަޔެއްގެ މައްޗަށް ތައުބާ ލައްވާނެތެވެ. ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","16","أَمۡ حَسِبۡتُمۡ أَن تُتۡرَكُواْ وَلَمَّا يَعۡلَمِ ٱللَّهُ ٱلَّذِينَ جَٰهَدُواْ مِنكُمۡ وَلَمۡ يَتَّخِذُواْ مِن دُونِ ٱللَّهِ وَلَا رَسُولِهِۦ وَلَا ٱلۡمُؤۡمِنِينَ وَلِيجَةٗۚ وَٱللَّهُ خَبِيرُۢ بِمَا تَعۡمَلُونَ ١٦","أم حسبتم أن تتركوا ولما يعلم الله الذين جاهدوا منكم ولم يتخذوا من دون الله ولا رسوله ولا المؤمنين وليجة والله خبير بما تعملون","ތިޔަބައިމީހުންކުރެ ޖިހާދު ކޮށް، ﷲއާއި، އެކަލާނގެ ރަސޫލާއާއި، މުއުމިނުން ފިޔަވައި، އެކުވެރިން ބޭނުންނުކުރާ މީހުން، ﷲ ދެނެވޮޑިގެންވާކަން އެންގެވުމުގެ ގޮތުން، އިމްތިހާނުކުރެއްވުމަކާނުލައި، ތިޔަބައިމީހުން ދޫކޮށްލައްވާނެކަމަށް ތިޔަބައިމީހުން ހީކުރީހެއްޔެވެ؟ ﷲއީ، ތިޔަބައިމީހުންކުރާ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","17","مَا كَانَ لِلۡمُشۡرِكِينَ أَن يَعۡمُرُواْ مَسَٰجِدَ ٱللَّهِ شَٰهِدِينَ عَلَىٰٓ أَنفُسِهِم بِٱلۡكُفۡرِۚ أُوْلَـٰٓئِكَ حَبِطَتۡ أَعۡمَٰلُهُمۡ وَفِي ٱلنَّارِ هُمۡ خَٰلِدُونَ ١٧","ما كان للمشركين أن يعمروا مساجد الله شاهدين على أنفسهم بالكفر أولئك حبطت أعمالهم وفي النار هم خالدون","އެއުރެންގެ އަމިއްލަ ނަފްސުތަކުގެ މައްޗަށް ކާފިރުކަމަށް ހެކިވެތިބި ޙާލުގައި، ﷲގެ މިސްކިތްތައް ފަޅުފިލުވައި ބެލެހެއްޓުމަކީ، މުޝްރިކުންނަށް އޮތްކަމެއްނޫނެވެ. އެއުރެންނަކީ، އެއުރެންގެ ޢަމަލުތައް ބާތިލު ވެފައިވާ މީހުންނެވެ. އަދި ހަމަ، އެއުރެންނީ، ނަރަކައިގައި ދެމިތިބޭނޭ ބަޔެކެވެ.","",""],["₉ سورة التوبة","18","إِنَّمَا يَعۡمُرُ مَسَٰجِدَ ٱللَّهِ مَنۡ ءَامَنَ بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِ وَأَقَامَ ٱلصَّلَوٰةَ وَءَاتَى ٱلزَّكَوٰةَ وَلَمۡ يَخۡشَ إِلَّا ٱللَّهَۖ فَعَسَىٰٓ أُوْلَـٰٓئِكَ أَن يَكُونُواْ مِنَ ٱلۡمُهۡتَدِينَ ١٨","إنما يعمر مساجد الله من آمن بالله واليوم الآخر وأقام الصلاة وآتى الزكاة ولم يخش إلا الله فعسى أولئك أن يكونوا من المهتدين","ﷲގެ މިސްކިތްތައް ފަޅުފިލުވައި ބަލަހައްޓާނީ، ﷲއަށާއި، އާޚިރަތް ދުވަހަށް އީމާންވެ، ނަމާދު ގާއިމު ކޮށް، ޒަކާތް ދީ، ﷲއަށް މެނުވީ ބިރުނުގަންނަ މީހުންކަން ކަށަވަރެވެ. ފަހެ، އެއުރެންނަކީ، ތެދުމަގު ލިބިގެންވާ މީހުން ކަމުގައިވުން ގާތްބަޔެކެވެ.","",""],["₉ سورة التوبة","19","۞أَجَعَلۡتُمۡ سِقَايَةَ ٱلۡحَآجِّ وَعِمَارَةَ ٱلۡمَسۡجِدِ ٱلۡحَرَامِ كَمَنۡ ءَامَنَ بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِ وَجَٰهَدَ فِي سَبِيلِ ٱللَّهِۚ لَا يَسۡتَوُۥنَ عِندَ ٱللَّهِۗ وَٱللَّهُ لَا يَهۡدِي ٱلۡقَوۡمَ ٱلظَّـٰلِمِينَ ١٩","أجعلتم سقاية الحاج وعمارة المسجد الحرام كمن آمن بالله واليوم الآخر وجاهد في سبيل الله لا يستوون عند الله والله لا يهدي القوم الظالمين","ހައްޖުވެރިންނަށް ބޯފެންދީ، ހުރުމަތް ތެރިވެގެންވާ މިސްކިތް ފަޅުފިލުވައި، ބަލަހައްޓައިއުޅޭ މީހަކާއި، ﷲއަށާއި، އާޚިރަތް ދުވަހަށް އީމާންވެ، ﷲގެ މަގުގައި ޖިހާދު ކޮށްއުޅޭ މީހަކާ ދެމީހުން، އެއްފަދަކަމަށް ތިޔަބައިމީހުން ހަދަނީހެއްޔެވެ؟ ﷲގެ ހަޒުރަތުގައި އެ ދެބައިމީހުން، ހަމަހަމައެއް ނުވާނެތެވެ. އަނިޔާވެރި ބަޔަކަށް، ﷲ ތެދުމަގެއް ނުދައްކަވާނެތެވެ.","",""],["₉ سورة التوبة","20","ٱلَّذِينَ ءَامَنُواْ وَهَاجَرُواْ وَجَٰهَدُواْ فِي سَبِيلِ ٱللَّهِ بِأَمۡوَٰلِهِمۡ وَأَنفُسِهِمۡ أَعۡظَمُ دَرَجَةً عِندَ ٱللَّهِۚ وَأُوْلَـٰٓئِكَ هُمُ ٱلۡفَآئِزُونَ ٢٠","الذين آمنوا وهاجروا وجاهدوا في سبيل الله بأموالهم وأنفسهم أعظم درجة عند الله وأولئك هم الفائزون","އީމާންވެ، ހިޖުރަ ކޮށް، ﷲގެ މަގުގައި އެއުރެންގެ މުދާތަކާއި، ނަފްސު ތަކުން ޖިހާދު ކޮށް އުޅުނު މީހުންނީ، ﷲގެ ހަޒުރަތުގައި ދަރަޖަ އެންމެ މަތިވެރިވެގެންވާ މީހުންނެވެ. އަދި އެއުރެންނީ، ހަމަ، ނަސީބު ލިބިގެންވާ މީހުންނެވެ.","",""],["₉ سورة التوبة","21","يُبَشِّرُهُمۡ رَبُّهُم بِرَحۡمَةٖ مِّنۡهُ وَرِضۡوَٰنٖ وَجَنَّـٰتٖ لَّهُمۡ فِيهَا نَعِيمٞ مُّقِيمٌ ٢١","يبشرهم ربهم برحمة منه ورضوان وجنات لهم فيها نعيم مقيم","އެއުރެންގެ ވެރިރަސްކަލާނގެ، އެކަލާނގެ ހަޒުރަތުން އެއުރެންނަށް ރަހުމަތާއި، ރުހިވޮޑިގަތުމާއި، ސުވަރުގެތައް ހުރިކަމުގެ އުފާވެރި ޚަބަރު، އެއުރެންނަށް ދެއްވަތެވެ. އެތާނގައި، އެއުރެންނަށް އަބަދަށް ދެމިހުންނަނިވި ނިއުމަތްތައް ވެއެވެ.","",""],["₉ سورة التوبة","22","خَٰلِدِينَ فِيهَآ أَبَدًاۚ إِنَّ ٱللَّهَ عِندَهُۥٓ أَجۡرٌ عَظِيمٞ ٢٢","خالدين فيها أبدا إن الله عنده أجر عظيم","އެތާނގައި، އެއުރެން އަބަދަށް ދެމިތިބެނިވި ގޮތުގައެވެ. ހަމަކަށަވަރުން، ﷲގެ ހަޒުރަތުގައި ބޮޑުވެގެންވާ ދަރުމަހުށްޓެވެ.","",""],["₉ سورة التوبة","23","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ لَا تَتَّخِذُوٓاْ ءَابَآءَكُمۡ وَإِخۡوَٰنَكُمۡ أَوۡلِيَآءَ إِنِ ٱسۡتَحَبُّواْ ٱلۡكُفۡرَ عَلَى ٱلۡإِيمَٰنِۚ وَمَن يَتَوَلَّهُم مِّنكُمۡ فَأُوْلَـٰٓئِكَ هُمُ ٱلظَّـٰلِمُونَ ٢٣","يا أيها الذين آمنوا لا تتخذوا آباءكم وإخوانكم أولياء إن استحبوا الكفر على الإيمان ومن يتولهم منكم فأولئك هم الظالمون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ މައިންބަފައިންނާއި، އެއްބަނޑުއެއްބަފާ މީހުން (ވިޔަސް) އެއުރެން އީމާންކަމަށްވުރެ ބޮޑަށް، ކާފިރުކަމަށް ލޯބިކުރާނަމަ، އެއީ ތިޔަބައިމީހުންގެ އެހީތެރި، އެކުވެރިން ކަމުގައި ނުހިފާށެވެ! އަދި އެއުރެންނަކީ، އެހީތެރި އެކުވެރިން ކަމުގައި، ތިޔަބައިމީހުންގެ ތެރެއިން ބަލާމީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ، ހަމަ، އަނިޔާވެރިންނެވެ.","",""],["₉ سورة التوبة","24","قُلۡ إِن كَانَ ءَابَآؤُكُمۡ وَأَبۡنَآؤُكُمۡ وَإِخۡوَٰنُكُمۡ وَأَزۡوَٰجُكُمۡ وَعَشِيرَتُكُمۡ وَأَمۡوَٰلٌ ٱقۡتَرَفۡتُمُوهَا وَتِجَٰرَةٞ تَخۡشَوۡنَ كَسَادَهَا وَمَسَٰكِنُ تَرۡضَوۡنَهَآ أَحَبَّ إِلَيۡكُم مِّنَ ٱللَّهِ وَرَسُولِهِۦ وَجِهَادٖ فِي سَبِيلِهِۦ فَتَرَبَّصُواْ حَتَّىٰ يَأۡتِيَ ٱللَّهُ بِأَمۡرِهِۦۗ وَٱللَّهُ لَا يَهۡدِي ٱلۡقَوۡمَ ٱلۡفَٰسِقِينَ ٢٤","قل إن كان آباؤكم وأبناؤكم وإخوانكم وأزواجكم وعشيرتكم وأموال اقترفتموها وتجارة تخشون كسادها ومساكن ترضونها أحب إليكم من الله ورسوله وجهاد في سبيله فتربصوا حتى يأتي الله بأمره والله لا يهدي القوم الفاسقين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންގެ މައިންބަފައިންނާއި، ދަރިންނާއި، އަޚްނާއި، އަނބިންނާއި، ގާތްތިމާގެ މީހުންނާއި، ތިޔަބައިމީހުން ހޯދާފައިވާ މުދާތަކާއި، ގެއްލުންވެދާނެކަމަށް ތިޔަބައިމީހުން ބިރުގަންނަ ވިޔަފާރިއާއި، ތިޔަބައިމީހުން ހިތްރުހޭ ގެދޮރާއި (މިހުރިހައި ތަކެތި) ﷲއާއި، އެކަލާނގެ ރަސޫލާއާއި، އެކަލާނގެ މަގުގައި ޖިހާދުކުރުމަށްވުރެން، ތިޔަބައިމީހުންނަށް ލޯބިވެތި ކަމުގައިވާނަމަ، ﷲގެ އަމުރުފުޅު އަތުވެއްޖައުމަށް ދާނދެން ތިޔަބައިމީހުން ބަލަބަލައި ތިބޭށެވެ! ފާސިގު ވީ މީހުންނަށް، ﷲ ތެދުމަގެއް ނުދައްކަވާނެތެވެ.","",""],["₉ سورة التوبة","25","لَقَدۡ نَصَرَكُمُ ٱللَّهُ فِي مَوَاطِنَ كَثِيرَةٖ وَيَوۡمَ حُنَيۡنٍ إِذۡ أَعۡجَبَتۡكُمۡ كَثۡرَتُكُمۡ فَلَمۡ تُغۡنِ عَنكُمۡ شَيۡـٔٗا وَضَاقَتۡ عَلَيۡكُمُ ٱلۡأَرۡضُ بِمَا رَحُبَتۡ ثُمَّ وَلَّيۡتُم مُّدۡبِرِينَ ٢٥","لقد نصركم الله في مواطن كثيرة ويوم حنين إذ أعجبتكم كثرتكم فلم تغن عنكم شيئا وضاقت عليكم الأرض بما رحبت ثم وليتم مدبرين","ހަމަކަށަވަރުން، އެތައްއެތައް ތަނެއްގައި، ﷲ ތިޔަބައިމީހުންނަށް ނަސްރު ދެއްވިއެވެ. އަދި ޙުނައިނު (ހަނގުރާމައިގެ) ދުވަހު، ތިޔަބައިމީހުންގެ ބައިގިނަކަމުގެ ސަބަބުން، ތިޔަބައިމީހުން ހެއްލުންތެރިވީހިނދު، ހަނދުމަކުރާށެވެ! ފަހެ، އެ ބައިގިނަކަން، ތިޔަބައިމީހުންނަށް އެއްވެސްކަމެއް ފުއްދައެއްނުދިނެވެ. އަދި (އެހިނދު) ތަނަވަސްކޮށް އޮތް ބިން، ތިޔަބައިމީހުންނަށް ދަތިވެގެންދިޔައެވެ. ދެން ތިޔަބައިމީހުން، ފުރަގަސްދީ، ފިލާން ދުއްވައިގަތީމުއެވެ.","",""],["₉ سورة التوبة","26","ثُمَّ أَنزَلَ ٱللَّهُ سَكِينَتَهُۥ عَلَىٰ رَسُولِهِۦ وَعَلَى ٱلۡمُؤۡمِنِينَ وَأَنزَلَ جُنُودٗا لَّمۡ تَرَوۡهَا وَعَذَّبَ ٱلَّذِينَ كَفَرُواْۚ وَذَٰلِكَ جَزَآءُ ٱلۡكَٰفِرِينَ ٢٦","ثم أنزل الله سكينته على رسوله وعلى المؤمنين وأنزل جنودا لم تروها وعذب الذين كفروا وذلك جزاء الكافرين","ދެން ﷲ އެކަލާނގެ ރަސޫލާއަށާއި، އީމާންވި މީސްތަކުންގެ މައްޗަށް އެކަލާނގެ (ހަޒުރަތުން) ހިތްހަމަޖެހުން ބާވައިލައްވައި، އަދި ތިޔަބައިމީހުންނަށް ނުފެންނަ ލަޝްކަރެއް ބާވައިލެއްވިއެވެ. އަދި ކާފިރުވި މީހުންނަށް އެކަލާނގެ އަޒާބު ދެއްވިއެވެ. އެއީ ކާފިރުންގެ ޖަޒާއެވެ.","",""],["₉ سورة التوبة","27","ثُمَّ يَتُوبُ ٱللَّهُ مِنۢ بَعۡدِ ذَٰلِكَ عَلَىٰ مَن يَشَآءُۗ وَٱللَّهُ غَفُورٞ رَّحِيمٞ ٢٧","ثم يتوب الله من بعد ذلك على من يشاء والله غفور رحيم","ދެން އޭގެފަހުން، ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ތައުބާ ލައްވަތެވެ. ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","28","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ إِنَّمَا ٱلۡمُشۡرِكُونَ نَجَسٞ فَلَا يَقۡرَبُواْ ٱلۡمَسۡجِدَ ٱلۡحَرَامَ بَعۡدَ عَامِهِمۡ هَٰذَاۚ وَإِنۡ خِفۡتُمۡ عَيۡلَةٗ فَسَوۡفَ يُغۡنِيكُمُ ٱللَّهُ مِن فَضۡلِهِۦٓ إِن شَآءَۚ إِنَّ ٱللَّهَ عَلِيمٌ حَكِيمٞ ٢٨","يا أيها الذين آمنوا إنما المشركون نجس فلا يقربوا المسجد الحرام بعد عامهم هذا وإن خفتم عيلة فسوف يغنيكم الله من فضله إن شاء إن الله عليم حكيم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! މުޝްރިކުންނަކީ، ނަޖިސް ބަޔެއްކަން ކަށަވަރެވެ. ފަހެ، މިއަހަރަށްފަހު، ހުރުމަތް ތެރިވެގެންވާ މިސްކިތާ އެއުރެން، ކައިރިވިޔަ ނުދޭހުށިކަމެވެ! އަދި ތިޔަބައިމީހުން، ފަގީރު ވެދާނޭކަމަށް ބިރުގަންނަނަމަ، ފަހެ، ﷲ އިރާދަކުރައްވައިފިއްޔާ، އެކަލާނގެ ފަޟްލު ވަންތަކަމުން، ތިޔަބައިމީހުން މުއްސަނދި ކުރައްވައިފާނެތެވެ. ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","29","قَٰتِلُواْ ٱلَّذِينَ لَا يُؤۡمِنُونَ بِٱللَّهِ وَلَا بِٱلۡيَوۡمِ ٱلۡأٓخِرِ وَلَا يُحَرِّمُونَ مَا حَرَّمَ ٱللَّهُ وَرَسُولُهُۥ وَلَا يَدِينُونَ دِينَ ٱلۡحَقِّ مِنَ ٱلَّذِينَ أُوتُواْ ٱلۡكِتَٰبَ حَتَّىٰ يُعۡطُواْ ٱلۡجِزۡيَةَ عَن يَدٖ وَهُمۡ صَٰغِرُونَ ٢٩","قاتلوا الذين لا يؤمنون بالله ولا باليوم الآخر ولا يحرمون ما حرم الله ورسوله ولا يدينون دين الحق من الذين أوتوا الكتاب حتى يعطوا الجزية عن يد وهم صاغرون","ފޮތް ލިބުނު މީހުންކުރެ، ﷲއަށާއި، އާޚިރަތް ދުވަހަށް އީމާން ނުވާ، އަދި ﷲއާއި، އެކަލާނގެ ރަސޫލާ ހަރާމްކުރެއްވި ކަންތައް ހަރާމް ނުކުރާ، އަދި ހައްގު ދީނަށް ތަބާ ނުވާ މީހުންނާ ތިޔަބައިމީހުން ހަނގުރާމަ ކުރާށެވެ! (އެއީ) އެއުރެން ނިކަމެތިވެ، ދެރަވެގެންވާ ޙާލު، އަމިއްލައަތުން ޖިޒުޔަ ދީފުމަށް ދާނދެނެވެ.","",""],["₉ سورة التوبة","30","وَقَالَتِ ٱلۡيَهُودُ عُزَيۡرٌ ٱبۡنُ ٱللَّهِ وَقَالَتِ ٱلنَّصَٰرَى ٱلۡمَسِيحُ ٱبۡنُ ٱللَّهِۖ ذَٰلِكَ قَوۡلُهُم بِأَفۡوَٰهِهِمۡۖ يُضَٰهِـُٔونَ قَوۡلَ ٱلَّذِينَ كَفَرُواْ مِن قَبۡلُۚ قَٰتَلَهُمُ ٱللَّهُۖ أَنَّىٰ يُؤۡفَكُونَ ٣٠","وقالت اليهود عزير ابن الله وقالت النصارى المسيح ابن الله ذلك قولهم بأفواههم يضاهئون قول الذين كفروا من قبل قاتلهم الله أنى يؤفكون","ޔަހޫދީން ބުނޫއެވެ. ޢުޒައިރުގެފާނަކީ، ﷲގެ ދަރިކަލުންނެވެ. އަދި ނަސާރާ އިން ބުނޫއެވެ. އަލްމަސީޙު (ޢީސާގެފާނު) އަކީ، ﷲގެ ދަރިކަލުންނެވެ. އެއީ (ހަމައެކަނި) އެއުރެންގެ އަނގައިން ބުނެލާ ބަހެކެވެ. އެއުރެން އެ ތަގުލީދުކުރަނީ، އެއުރެންގެ ކުރިން ކާފިރުވި މީހުން ބުނެއުޅުނުފަދަ ބަހަކަށެވެ. ﷲ، އެއުރެންނަށް ލައުނަތް ލައްވާހުށްޓެވެ. އެއުރެން ހައްގުން އެއްކިބާވަނީ، ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["₉ سورة التوبة","31","ٱتَّخَذُوٓاْ أَحۡبَارَهُمۡ وَرُهۡبَٰنَهُمۡ أَرۡبَابٗا مِّن دُونِ ٱللَّهِ وَٱلۡمَسِيحَ ٱبۡنَ مَرۡيَمَ وَمَآ أُمِرُوٓاْ إِلَّا لِيَعۡبُدُوٓاْ إِلَٰهٗا وَٰحِدٗاۖ لَّآ إِلَٰهَ إِلَّا هُوَۚ سُبۡحَٰنَهُۥ عَمَّا يُشۡرِكُونَ ٣١","اتخذوا أحبارهم ورهبانهم أربابا من دون الله والمسيح ابن مريم وما أمروا إلا ليعبدوا إلها واحدا لا إله إلا هو سبحانه عما يشركون","އެއުރެންގެ އިލްމުވެރިންނާއި، ފާދިރީންނާއި، މަރިޔަމްގެފާނުގެ ދަރިކަލުން އަލްމަސީޙު (ޢީސާގެފާނު) އަކީ، ﷲ ފިޔަވައި އިލާހުން ކަމުގައި އެއުރެން ހެދޫއެވެ. (ނަމަވެސް) އެއްކައުވަންތަ އިލާހަށް، އަޅުކަން ކުޅައުމަށް މެނުވީ އެއުރެންނަށް އަމުރުކުރައްވާފައި ނުވެތެވެ. އެކަލާނގެ މެނުވީ އިލާހަކު ނުވެތެވެ. އެއުރެން އެ ޝަރީކުކުރާ ތަކެތިން، އެކަލާނގެ ހުސްތާހިރުވެ ވޮޑިގެންވެތެވެ.","",""],["₉ سورة التوبة","32","يُرِيدُونَ أَن يُطۡفِـُٔواْ نُورَ ٱللَّهِ بِأَفۡوَٰهِهِمۡ وَيَأۡبَى ٱللَّهُ إِلَّآ أَن يُتِمَّ نُورَهُۥ وَلَوۡ كَرِهَ ٱلۡكَٰفِرُونَ ٣٢","يريدون أن يطفئوا نور الله بأفواههم ويأبى الله إلا أن يتم نوره ولو كره الكافرون","އެއުރެން އެދެނީ، ﷲގެ ނޫރުފުޅު (އެބަހީ: އިސްލާމް ދީން) އެއުރެންގެ އަނގަތަކުން ފުމެ، ނިއްވާލުމަށެވެ. ނަމަވެސް، ކާފިރުން ކިތަންމެ ނުރުހުނަސް، ﷲ، އެކަލާނގެ ނޫރުފުޅު ފުރިހަމަކުރެއްވުމަށް މެނުވީ، އެކަލާނގެ އިރާދައެއް ނުކުރައްވަތެވެ.","",""],["₉ سورة التوبة","33","هُوَ ٱلَّذِيٓ أَرۡسَلَ رَسُولَهُۥ بِٱلۡهُدَىٰ وَدِينِ ٱلۡحَقِّ لِيُظۡهِرَهُۥ عَلَى ٱلدِّينِ كُلِّهِۦ وَلَوۡ كَرِهَ ٱلۡمُشۡرِكُونَ ٣٣","هو الذي أرسل رسوله بالهدى ودين الحق ليظهره على الدين كله ولو كره المشركون","އެކަލާނގެއީ، ތެދުމަގާއި، ހައްގު ދީނާއިގެން އެކަލާނގެ ރަސޫލާ ފޮނުއްވި ކަލާނގެއެވެ. (އެއީ) މުޝްރިކުން ނުރުހުނު ކަމުގައިވިޔަސް، އެންމެހާ ދީންތަކުގެ މައްޗަށް އެ ދީން ފާޅުކުރެއްވުމަށްޓަކައެވެ.","",""],["₉ سورة التوبة","34","۞يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ إِنَّ كَثِيرٗا مِّنَ ٱلۡأَحۡبَارِ وَٱلرُّهۡبَانِ لَيَأۡكُلُونَ أَمۡوَٰلَ ٱلنَّاسِ بِٱلۡبَٰطِلِ وَيَصُدُّونَ عَن سَبِيلِ ٱللَّهِۗ وَٱلَّذِينَ يَكۡنِزُونَ ٱلذَّهَبَ وَٱلۡفِضَّةَ وَلَا يُنفِقُونَهَا فِي سَبِيلِ ٱللَّهِ فَبَشِّرۡهُم بِعَذَابٍ أَلِيمٖ ٣٤","يا أيها الذين آمنوا إن كثيرا من الأحبار والرهبان ليأكلون أموال الناس بالباطل ويصدون عن سبيل الله والذين يكنزون الذهب والفضة ولا ينفقونها في سبيل الله فبشرهم بعذاب أليم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ހަމަކަށަވަރުން (ޔަހޫދީންގެ) އިލްމުވެރިންގެ ތެރެއިންނާއި (ނަސާރާ އިންގެ) ފާދިރީންގެ ތެރެއިން، ގިނަ މީހުން، މީސްތަކުންގެ މުދާތައް ބާތިލު ގޮތުގައި (އަތުލައި) ކައިއުޅެތެވެ. އަދި ﷲގެ މަގުން (މީސްތަކުން) ދުރުކުރެތެވެ. އަދި ރަނާއި ރިހި ޚަޒާނާ ކޮށް، ﷲގެ މަގުގައި އެތަކެތި ހޭދަނުކޮށް ތިބޭ މީހުން (ދަންނާށެވެ!) ފަހެ، ވޭންދެނިވި އަޒާބު ހުރިކަމުގެ ޚަބަރު، އެއުރެންނަށް ކަލޭގެފާނު ދެއްވާށެވެ!","",""],["₉ سورة التوبة","35","يَوۡمَ يُحۡمَىٰ عَلَيۡهَا فِي نَارِ جَهَنَّمَ فَتُكۡوَىٰ بِهَا جِبَاهُهُمۡ وَجُنُوبُهُمۡ وَظُهُورُهُمۡۖ هَٰذَا مَا كَنَزۡتُمۡ لِأَنفُسِكُمۡ فَذُوقُواْ مَا كُنتُمۡ تَكۡنِزُونَ ٣٥","يوم يحمى عليها في نار جهنم فتكوى بها جباههم وجنوبهم وظهورهم هذا ما كنزتم لأنفسكم فذوقوا ما كنتم تكنزون","(އެގޮތުގެމަތިން) އޭނާ، އެއްކޮށް ޚަޒާނާކުޅަ، ރަންރިހި، އެދުވަހުން ނަރަކައިގެ އަލިފާނުން ދޮންކުރައްވައި، އެތަކެތިން، އެއުރެންގެ ނިތްކުރިތަކުގައްޔާއި، އަރިކަށިތަކުގައްޔާއި، ބުރިކަށިތަކުގައި، ފާހަގަލައްވަމުން ގެންދަވާނެތެވެ. (އަދި އަންގަވާނެތެވެ.) މިހިރީ، ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސު ތަކަށްޓަކައި، ތިޔަބައިމީހުން އެއްކޮށް ޚަޒާނާކުޅަ ތަކެއްޗެވެ. ފަހެ، ތިޔަބައިމީހުން ޚަޒާނާ ކޮށް އުޅުނު ތަކެތީގެ ރަހަ ދެކެބަލާށެވެ!","",""],["₉ سورة التوبة","36","إِنَّ عِدَّةَ ٱلشُّهُورِ عِندَ ٱللَّهِ ٱثۡنَا عَشَرَ شَهۡرٗا فِي كِتَٰبِ ٱللَّهِ يَوۡمَ خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضَ مِنۡهَآ أَرۡبَعَةٌ حُرُمٞۚ ذَٰلِكَ ٱلدِّينُ ٱلۡقَيِّمُۚ فَلَا تَظۡلِمُواْ فِيهِنَّ أَنفُسَكُمۡۚ وَقَٰتِلُواْ ٱلۡمُشۡرِكِينَ كَآفَّةٗ كَمَا يُقَٰتِلُونَكُمۡ كَآفَّةٗۚ وَٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ مَعَ ٱلۡمُتَّقِينَ ٣٦","إن عدة الشهور عند الله اثنا عشر شهرا في كتاب الله يوم خلق السماوات والأرض منها أربعة حرم ذلك الدين القيم فلا تظلموا فيهن أنفسكم وقاتلوا المشركين كافة كما يقاتلونكم كافة واعلموا أن الله مع المتقين","ހަމަކަށަވަރުން، އުޑުތަކާއި، ބިން ހެއްދެވި ދުވަހުއްސުރެން، ﷲ ކަނޑައަޅުއްވާފައިވާ ގޮތުގައި (އަހަރެއްގެ) މައްސަރުތަކުގެ އަދަދަކީ، ﷲގެ ހަޒުރަތުގައި ބާރަ މަހެވެ. އޭގެތެރެއިން، ހަތަރު މަސް، ހުރުމަތް ތެރި ވެގެންވެއެވެ. އެއީ ހައްގު ތެދު ދީނެވެ. ފަހެ، އެ މައްސަރުތަކުގައި، ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތަކަށް ތިޔަބައިމީހުން އަނިޔާ ނުކުރާހުށިކަމެވެ! އަދި އެންމެހާ މުޝްރިކުންނާ ތިޔަބައިމީހުން ހަނގުރާމަކުރާށެވެ! އެއުރެންވެސް އެންމެން އެކުގައި ތިޔަބައިމީހުންނާ ހަނގުރާމަކުރާ ފަދައިންނެވެ. އަދި ހަމަކަށަވަރުން، ﷲ ވޮޑިގެންވަނީ، ތަގުވާވެރިންނާ އެކުގައިކަން، ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₉ سورة التوبة","37","إِنَّمَا ٱلنَّسِيٓءُ زِيَادَةٞ فِي ٱلۡكُفۡرِۖ يُضَلُّ بِهِ ٱلَّذِينَ كَفَرُواْ يُحِلُّونَهُۥ عَامٗا وَيُحَرِّمُونَهُۥ عَامٗا لِّيُوَاطِـُٔواْ عِدَّةَ مَا حَرَّمَ ٱللَّهُ فَيُحِلُّواْ مَا حَرَّمَ ٱللَّهُۚ زُيِّنَ لَهُمۡ سُوٓءُ أَعۡمَٰلِهِمۡۗ وَٱللَّهُ لَا يَهۡدِي ٱلۡقَوۡمَ ٱلۡكَٰفِرِينَ ٣٧","إنما النسيء زيادة في الكفر يضل به الذين كفروا يحلونه عاما ويحرمونه عاما ليواطئوا عدة ما حرم الله فيحلوا ما حرم الله زين لهم سوء أعمالهم والله لا يهدي القوم الكافرين","ހަމަކަށަވަރުން، (ހުރުމަތް ތެރި މައްސަރެއް) ފަސްކޮށްލުމަކީ، ކާފިރު ކަން އިތުރު ކުރުމެކެވެ. ކާފިރުވި މީހުން އެކަމުގެ ސަބަބުން (އިތުރަށް) މަގުފުރެދިގެންދެތެވެ. އެއުރެން އެއްއަހަރު އެއްމައްސަރެއްގެ ހުރުމަތް ކަނޑައި، އަނެއްއަހަރު އެ މައްސަރެއް ހުރުމަތް ތެރި ކުރެތެވެ. އެއީ ﷲ، ހުރުމަތް ތެރި ކުރައްވާފައިވާ މައްސަރުތަކުގެ އަދަދު ހަމަކުޅައުމަށްޓަކައެވެ. ފަހެ، އެގޮތުން، ﷲ ހުރުމަތް ތެރި ކުރައްވާފައިވާ މައްސަރުތަކުގެ ހުރުމަތް ކަނޑަތެވެ. އެއުރެންގެ ނުބައި ޢަމަލުތައް، އެއުރެންނަށް ޒީނަތްތެރި ކުރެއްވިއެވެ. ކާފިރުވި މީހުންނަކަށް، ﷲ ތެދުމަގެއް ނުދައްކަވަތެވެ.","",""],["₉ سورة التوبة","38","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ مَا لَكُمۡ إِذَا قِيلَ لَكُمُ ٱنفِرُواْ فِي سَبِيلِ ٱللَّهِ ٱثَّاقَلۡتُمۡ إِلَى ٱلۡأَرۡضِۚ أَرَضِيتُم بِٱلۡحَيَوٰةِ ٱلدُّنۡيَا مِنَ ٱلۡأٓخِرَةِۚ فَمَا مَتَٰعُ ٱلۡحَيَوٰةِ ٱلدُّنۡيَا فِي ٱلۡأٓخِرَةِ إِلَّا قَلِيلٌ ٣٨","يا أيها الذين آمنوا ما لكم إذا قيل لكم انفروا في سبيل الله اثاقلتم إلى الأرض أرضيتم بالحياة الدنيا من الآخرة فما متاع الحياة الدنيا في الآخرة إلا قليل","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ﷲގެ މަގުގައި ހަނގުރާމަ ކުރުމަށް ނުކުންނާށޭ ތިޔަބައިމީހުންނަށް އެންގެވިހިނދު، ތިޔަބައިމީހުން ބިމަށް ބަރުހެލިވެގަތީ ކީއްވެގެންހެއްޔެވެ؟ އާޚިރަތަށްވުރެ ދުނިޔޭގެ ދިރިހުރުމަށް ތިޔަބައިމީހުން ރުހުނީހެއްޔެވެ؟ ދުނިޔޭގެ އުފަލާއި، އަރާމަކީ އާޚިރަތާ އަޅައިބަލާއިރު، މަދުއެތިކޮޅެއް ކަމުގައި ނޫނީ ނުވެތެވެ.","",""],["₉ سورة التوبة","39","إِلَّا تَنفِرُواْ يُعَذِّبۡكُمۡ عَذَابًا أَلِيمٗا وَيَسۡتَبۡدِلۡ قَوۡمًا غَيۡرَكُمۡ وَلَا تَضُرُّوهُ شَيۡـٔٗاۗ وَٱللَّهُ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٌ ٣٩","إلا تنفروا يعذبكم عذابا أليما ويستبدل قوما غيركم ولا تضروه شيئا والله على كل شيء قدير","ތިޔަބައިމީހުން (ހަނގުރާމައަށް) ނުނިކުންނަނަމަ، ވޭންދެނިވި އަޒާބަކުން އެކަލާނގެ ތިޔަބައިމީހުންނަށް އަޒާބު ދެއްވާނެތެވެ. އަދި ތިޔަބައިމީހުންގެ ބަދަލުގައި، އެހެންބަޔަކު ގެންނަވައިފާނެތެވެ. އަދި ތިޔަބައިމީހުންނަކަށް، އެއްވެސް ކަމަކުން އެކަލާނގެއަށް ގެއްލުމެއް ނުދެވޭނެތެވެ. ﷲއީ ކޮންމެކަމެއްގެމައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","40","إِلَّا تَنصُرُوهُ فَقَدۡ نَصَرَهُ ٱللَّهُ إِذۡ أَخۡرَجَهُ ٱلَّذِينَ كَفَرُواْ ثَانِيَ ٱثۡنَيۡنِ إِذۡ هُمَا فِي ٱلۡغَارِ إِذۡ يَقُولُ لِصَٰحِبِهِۦ لَا تَحۡزَنۡ إِنَّ ٱللَّهَ مَعَنَاۖ فَأَنزَلَ ٱللَّهُ سَكِينَتَهُۥ عَلَيۡهِ وَأَيَّدَهُۥ بِجُنُودٖ لَّمۡ تَرَوۡهَا وَجَعَلَ كَلِمَةَ ٱلَّذِينَ كَفَرُواْ ٱلسُّفۡلَىٰۗ وَكَلِمَةُ ٱللَّهِ هِيَ ٱلۡعُلۡيَاۗ وَٱللَّهُ عَزِيزٌ حَكِيمٌ ٤٠","إلا تنصروه فقد نصره الله إذ أخرجه الذين كفروا ثاني اثنين إذ هما في الغار إذ يقول لصاحبه لا تحزن إن الله معنا فأنزل الله سكينته عليه وأيده بجنود لم تروها وجعل كلمة الذين كفروا السفلى وكلمة الله هي العليا والله عزيز حكيم","ތިޔަބައިމީހުން އެކަލޭގެފާނަށް ނަސްރު ނުދިނަސް، ހަމަކަށަވަރުން، ﷲ، އެކަލޭގެފާނަށް ނަސްރު ދެއްވިއެވެ. ދެމީހުންކުރެ އެކަކު ކަމުގައިވާ ޙާލު، ކާފިރުވި މީހުން، އެކަލޭގެފާނު ނެރެލިހިނދުގައެވެ. އޭގެ ދެކަލުން (ޘައުރު ފަރުބަދައިގެ) ހޮހަޅައިގައި ތިއްބެވި ހިނދުގައެވެ. އެކަލޭގެފާނުގެ އެކުވެރިޔާއަށް، ހިތާމަނުކުރައްވާށޭ، ހަމަކަށަވަރުން، ﷲ ވޮޑިގެންވަނީ، ތިމަންމެންނާ އެކުގައޭ ވިދާޅުވިހިނދުގައެވެ. އެހިނދު އެކަލޭގެފާނަށް ހިތްޕުޅު ހަމަޖެހުމާއި، އަމާންކަން ﷲ ބާވައިލެއްވިއެވެ. އަދި ތިޔަބައިމީހުންނަށް ނުފެންނަ ލަޝްކަރު ތަކަކުން އެކަލޭގެފާނަށް އެކަލާނގެ ގަދަކަން ދެއްވިއެވެ. އަދި ކާފިރުވި މީހުންގެ ބަސް، އެންމެ ދަށްވެގެންވާ ބަސްކަމުގައި ލެއްވިއެވެ. ﷲގެ ބަސްފުޅު އެއީ، އެންމެ މަތިވެރިވެގެންވާ ބަސްފުޅުކަމުގައި ލެއްވިއެވެ. ﷲއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","41","ٱنفِرُواْ خِفَافٗا وَثِقَالٗا وَجَٰهِدُواْ بِأَمۡوَٰلِكُمۡ وَأَنفُسِكُمۡ فِي سَبِيلِ ٱللَّهِۚ ذَٰلِكُمۡ خَيۡرٞ لَّكُمۡ إِن كُنتُمۡ تَعۡلَمُونَ ٤١","انفروا خفافا وثقالا وجاهدوا بأموالكم وأنفسكم في سبيل الله ذلكم خير لكم إن كنتم تعلمون","ލުއިކަމާއެކުގައްޔާއި، ބުރަކަމާއެކުގައި، ތިޔަބައިމީހުން (ހަނގުރާމައަށް) ނުކުންނާށެވެ! އަދި ތިޔަބައިމީހުންގެ މުދާތަކާއި، ނަފްސު ތަކުން ﷲގެ މަގުގައި ޖިހާދުކުރާށެވެ! ތިޔަބައިމީހުންނަށްޓަކައި، އެގޮތް ހެޔޮކަން ބޮޑެވެ. ތިޔަބައިމީހުންނަށް (އެކަން) އެނގޭކަމުގައި ވާނަމައެވެ.","",""],["₉ سورة التوبة","42","لَوۡ كَانَ عَرَضٗا قَرِيبٗا وَسَفَرٗا قَاصِدٗا لَّٱتَّبَعُوكَ وَلَٰكِنۢ بَعُدَتۡ عَلَيۡهِمُ ٱلشُّقَّةُۚ وَسَيَحۡلِفُونَ بِٱللَّهِ لَوِ ٱسۡتَطَعۡنَا لَخَرَجۡنَا مَعَكُمۡ يُهۡلِكُونَ أَنفُسَهُمۡ وَٱللَّهُ يَعۡلَمُ إِنَّهُمۡ لَكَٰذِبُونَ ٤٢","لو كان عرضا قريبا وسفرا قاصدا لاتبعوك ولكن بعدت عليهم الشقة وسيحلفون بالله لو استطعنا لخرجنا معكم يهلكون أنفسهم والله يعلم إنهم لكاذبون","ގާތުގައި އޮތް ދުނިޔަވީ މަންފާއެއް ކަމުގައި، ނުވަތަ ލުއިފަސޭހަ ދަތުރެއް ކަމުގައިވީނަމަ، އެއުރެން ކަލޭގެފާނުގެ ފަހަތްޕުޅުން ހިނގައްޖައީސްކަން ކަށަވަރެވެ. އެހެނެއްކަމަކު، ދަތުރުކުރާންއޮތް މަގު، އެއުރެންނަށް ދުރުވީއެވެ. އަދި ތިމަންމެންނަށް ކުޅަދާނަވެގެންވީނަމަ، ތިޔަބައިމީހުންނާއެކު ނުކުތީމުހޭ ކިޔައި، އެއުރެން ﷲ ގަންދީ ހުވާކޮށް ހަދާނެތެވެ. އެއުރެން (އެކަމުން) އެއުރެންގެ އަމިއްލަ ނަފްސުތައް ހަލާކުކުރެތެވެ. ހަމަކަށަވަރުން، އެއުރެންނީ ދޮގުވެރިންކަން ﷲ ދެނެވޮޑިގެންވެތެވެ.","",""],["₉ سورة التوبة","43","عَفَا ٱللَّهُ عَنكَ لِمَ أَذِنتَ لَهُمۡ حَتَّىٰ يَتَبَيَّنَ لَكَ ٱلَّذِينَ صَدَقُواْ وَتَعۡلَمَ ٱلۡكَٰذِبِينَ ٤٣","عفا الله عنك لم أذنت لهم حتى يتبين لك الذين صدقوا وتعلم الكاذبين","ﷲ، ކަލޭގެފާނަށް އަފޫކުރައްވައިފިއެވެ. ތެދުބުނި މީހުން، ކަލޭގެފާނަށް ބަޔާންވެ ފާޅުވެ، ދޮގުވެރިން އެނގިވަޑައިގެންފުމަށްދާނދެން (ހަނގުރާމައަށް ނުގޮސްތިބުމަށް) އެއުރެންނަށް، ކަލޭގެފާނު އިޒުނަ ދެއްވީ ކީއްވެގެންތޯއެވެ؟","",""],["₉ سورة التوبة","44","لَا يَسۡتَـٔۡذِنُكَ ٱلَّذِينَ يُؤۡمِنُونَ بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِ أَن يُجَٰهِدُواْ بِأَمۡوَٰلِهِمۡ وَأَنفُسِهِمۡۗ وَٱللَّهُ عَلِيمُۢ بِٱلۡمُتَّقِينَ ٤٤","لا يستأذنك الذين يؤمنون بالله واليوم الآخر أن يجاهدوا بأموالهم وأنفسهم والله عليم بالمتقين","ﷲއަށާއި، އާޚިރަތް ދުވަހަށް އީމާންވާ މީހުން، އެއުރެންގެ މުދާތަކާއި، ނަފްސު ތަކުން ޖިހާދުކުރުމުން އެއްކިބާވެތިބުމަށް ކަލޭގެފާނުގެ އަރިހުން އިޒުނަކަށް ނޭދޭނެތެވެ. ﷲއީ، ތަގުވާވެރިން މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","45","إِنَّمَا يَسۡتَـٔۡذِنُكَ ٱلَّذِينَ لَا يُؤۡمِنُونَ بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِ وَٱرۡتَابَتۡ قُلُوبُهُمۡ فَهُمۡ فِي رَيۡبِهِمۡ يَتَرَدَّدُونَ ٤٥","إنما يستأذنك الذين لا يؤمنون بالله واليوم الآخر وارتابت قلوبهم فهم في ريبهم يترددون","(ހަނގުރާމައަށް ނުގޮސް ތިބުމަށް) ކަލޭގެފާނުގެ އަރިހުން އިޒުނަށް އެދެނީ، ﷲއަށާއި، އާޚިރަތް ދުވަހަށް އީމާން ނުވާ މީހުންކަން ކަށަވަރެވެ. އަދި އެއުރެންގެ ހިތްތަކުގައި، ޝައްކު ހިނގާ މީހުންނެވެ. ފަހެ، އެއުރެންގެ ޝައްކުކަމުގެ ތެރޭގައި، އެއުރެން ދެއަތަށް ކިރިކިރި ތިބެތެވެ.","",""],["₉ سورة التوبة","46","۞وَلَوۡ أَرَادُواْ ٱلۡخُرُوجَ لَأَعَدُّواْ لَهُۥ عُدَّةٗ وَلَٰكِن كَرِهَ ٱللَّهُ ٱنۢبِعَاثَهُمۡ فَثَبَّطَهُمۡ وَقِيلَ ٱقۡعُدُواْ مَعَ ٱلۡقَٰعِدِينَ ٤٦","ولو أرادوا الخروج لأعدوا له عدة ولكن كره الله انبعاثهم فثبطهم وقيل اقعدوا مع القاعدين","އެއުރެން (ހަނގުރާމައަށް) ނުކުތުމަށް އެދޭނަމަ، އެކަމަށް ހަތިޔާރާއި، ތަކެތި އެއުރެން ތައްޔާރުކުރީހެވެ. އެހެނެއްކަމަކު (ކަލޭގެފާނުގެ އަރިހުގައި) އެއުރެން ނުކުތުމަށް، ﷲ ނުރުއްސަވައިފިއެވެ. ދެން އެއުރެންގެ ހިތްވަރު ދެރަކުރައްވައި، ކަންނެތް ކުރެއްވިއެވެ. އަދި (ހަނގުރާމައަށް ނުގޮސް) އިށީނދެ ތިބޭ މީހުންނާއެކު، ތިޔަބައިމީހުން ތިބޭށޭ އެންގެވިއެވެ.","",""],["₉ سورة التوبة","47","لَوۡ خَرَجُواْ فِيكُم مَّا زَادُوكُمۡ إِلَّا خَبَالٗا وَلَأَوۡضَعُواْ خِلَٰلَكُمۡ يَبۡغُونَكُمُ ٱلۡفِتۡنَةَ وَفِيكُمۡ سَمَّـٰعُونَ لَهُمۡۗ وَٱللَّهُ عَلِيمُۢ بِٱلظَّـٰلِمِينَ ٤٧","لو خرجوا فيكم ما زادوكم إلا خبالا ولأوضعوا خلالكم يبغونكم الفتنة وفيكم سماعون لهم والله عليم بالظالمين","އެއުރެން ތިޔަބައިމީހުންގެ ތެރޭގައި (ހަނގުރާމައަށް) ނުކުތްނަމަ، ފަސާދަވެރިކަން ނޫންކަމެއް ތިޔަބައިމީހުންނަށް އެއުރެން އިތުރެއް ނުކުޅައީހެވެ. އަދި ތިޔަބައިމީހުންނަށް ފިތުނަވެރިކަން އެދިގެން ތިޔަބައިމީހުންގެ ތެރޭގައި މަސައްކަތް ކުޅައުމަށް އަވަސްވެގަތީހެވެ. އެއުރެން ދައްކާ ވާހަކަ އަހާ މީހުންވެސް ތިޔަބައިމީހުންގެ ތެރޭގައިވެއެވެ. ﷲއީ، އަނިޔާވެރިން މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","48","لَقَدِ ٱبۡتَغَوُاْ ٱلۡفِتۡنَةَ مِن قَبۡلُ وَقَلَّبُواْ لَكَ ٱلۡأُمُورَ حَتَّىٰ جَآءَ ٱلۡحَقُّ وَظَهَرَ أَمۡرُ ٱللَّهِ وَهُمۡ كَٰرِهُونَ ٤٨","لقد ابتغوا الفتنة من قبل وقلبوا لك الأمور حتى جاء الحق وظهر أمر الله وهم كارهون","ކުރިންވެސް އެއުރެން ފިތުނަވެރިކަމަށް އެދިގެން އުޅުނުކަން ކަށަވަރެވެ. އަދި ﷲގެ އަމުރުފުޅު ފާޅުވެ، ހައްގު ބަސްފުޅު އަތުވެއްޖައުމަށްދާނދެން، އެއުރެން (އެކަމަށް) ނުރުހޭ ޙާލުގައި، ކަލޭގެފާނަށް ކެހިދިނުމުގެ ކަންތައް އެއުރެން ރާވައި އުޅުނޫއެވެ.","",""],["₉ سورة التوبة","49","وَمِنۡهُم مَّن يَقُولُ ٱئۡذَن لِّي وَلَا تَفۡتِنِّيٓۚ أَلَا فِي ٱلۡفِتۡنَةِ سَقَطُواْۗ وَإِنَّ جَهَنَّمَ لَمُحِيطَةُۢ بِٱلۡكَٰفِرِينَ ٤٩","ومنهم من يقول ائذن لي ولا تفتني ألا في الفتنة سقطوا وإن جهنم لمحيطة بالكافرين","އަދި (ހަނގުރާމައަށް ނުގޮސްހުރުމުގެ) އިޒުނަ ތިމަންނާއަށް ދެއްވާށޭ، އަދި ތިމަން ފިތުނަވެރި ނުކުރައްވާށޭ ބުނާ މީހަކު، އެއުރެންގެ ތެރެއިން ވެތެވެ. ދަންނާށެވެ! އެއުރެން ވެއްޓިގެން އެދިޔައީ، ހަމަ، ފިތުނައިގެ ތެރެއަށެވެ. އަދި ހަމަކަށަވަރުން، ނަރަކަ ވަނީ، ކާފިރުން ވަށާލައިފައެވެ.","",""],["₉ سورة التوبة","50","إِن تُصِبۡكَ حَسَنَةٞ تَسُؤۡهُمۡۖ وَإِن تُصِبۡكَ مُصِيبَةٞ يَقُولُواْ قَدۡ أَخَذۡنَآ أَمۡرَنَا مِن قَبۡلُ وَيَتَوَلَّواْ وَّهُمۡ فَرِحُونَ ٥٠","إن تصبك حسنة تسؤهم وإن تصبك مصيبة يقولوا قد أخذنا أمرنا من قبل ويتولوا وهم فرحون","ކަލޭގެފާނަށް ހެޔޮގޮތެއް މެދުވެރިވެއްޖެނަމަ، އެކަން އެއުރެންނަށް ހިތާމައަކަށް ވެތެވެ. އަދި ކަލޭގެފާނަށް މުސީބަތެއް މެދުވެރިވެއްޖެނަމަ، އެއުރެން ބުނެތެވެ. ހަމަކަށަވަރުން، ތިމަންމެން ކުރިއްސުރެން މިތިބީ، ރައްކާތެރިކަމުގައި ހިފައިގެންނެވެ. އަދި އުފަލުންތިބެ، އެއުރެން އެނބުރި ހިނގައިދާނެތެވެ.","",""],["₉ سورة التوبة","51","قُل لَّن يُصِيبَنَآ إِلَّا مَا كَتَبَ ٱللَّهُ لَنَا هُوَ مَوۡلَىٰنَاۚ وَعَلَى ٱللَّهِ فَلۡيَتَوَكَّلِ ٱلۡمُؤۡمِنُونَ ٥١","قل لن يصيبنا إلا ما كتب الله لنا هو مولانا وعلى الله فليتوكل المؤمنون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲ އަޅަމެންނަށް ލިޔުއްވާފައިވާކަމެއް މެނުވީ، އަޅަމެންނަކަށް ނުޖެހޭނެތެވެ. އެކަލާނގެއީ، އަޅަމެންގެ އެހީތެރިވަންތަ ރަސްކަލާނގެއެވެ. ފަހެ، މުއުމިނުން ހަމައެކަނި، ﷲއަށް ވަކީލުކުރާހުށިކަމެވެ!","",""],["₉ سورة التوبة","52","قُلۡ هَلۡ تَرَبَّصُونَ بِنَآ إِلَّآ إِحۡدَى ٱلۡحُسۡنَيَيۡنِۖ وَنَحۡنُ نَتَرَبَّصُ بِكُمۡ أَن يُصِيبَكُمُ ٱللَّهُ بِعَذَابٖ مِّنۡ عِندِهِۦٓ أَوۡ بِأَيۡدِينَاۖ فَتَرَبَّصُوٓاْ إِنَّا مَعَكُم مُّتَرَبِّصُونَ ٥٢","قل هل تربصون بنا إلا إحدى الحسنيين ونحن نتربص بكم أن يصيبكم الله بعذاب من عنده أو بأيدينا فتربصوا إنا معكم متربصون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހެޔޮދެގޮތުން އެއްގޮތްނޫނީ، އަހަރެމެންނާމެދު ތިޔަބައިމީހުން އިންތިޒާރުކުރަމުހޭ؟ އަދި ތިމަންމެން ތިޔަބައިމީހުންނާމެދު އިންތިޒާރު ކޮށްކޮށް ތިބެނީ، އެކަލާނގެ ހަޒުރަތުން، ނުވަތަ ތިމަންމެންގެ އަތްމަތިން، ﷲ ތިޔަބައިމީހުންނަށް އަޒާބެއް ފޮނުއްވައިފާނެ ކަމަށެވެ. ފަހެ، ތިޔަބައިމީހުން އިންތިޒާރު ކޮށްކޮށް ތިބޭށެވެ! ހަމަކަށަވަރުން، ތިމަންމެންނީވެސް ތިޔަބައިމީހުންނާއެކު އިންތިޒާރުކުރާ ބަޔަކީމުއެވެ.","",""],["₉ سورة التوبة","53","قُلۡ أَنفِقُواْ طَوۡعًا أَوۡ كَرۡهٗا لَّن يُتَقَبَّلَ مِنكُمۡ إِنَّكُمۡ كُنتُمۡ قَوۡمٗا فَٰسِقِينَ ٥٣","قل أنفقوا طوعا أو كرها لن يتقبل منكم إنكم كنتم قوما فاسقين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ރުހުމުގައި، ނުވަތަ ނުރުހުމުގައި ހޭދަކުރިޔަސް، ތިޔަބައިމީހުންގެ ކިބަޔަކުން އެކަން ގަބޫލެއް ނުކުރައްވާ ހުށްޓެވެ. އެހެނީ ހަމަކަށަވަރުން، ތިޔަބައިމީހުންވީ، ފާސިގު ބަޔަކު ކަމުގައެވެ.","",""],["₉ سورة التوبة","54","وَمَا مَنَعَهُمۡ أَن تُقۡبَلَ مِنۡهُمۡ نَفَقَٰتُهُمۡ إِلَّآ أَنَّهُمۡ كَفَرُواْ بِٱللَّهِ وَبِرَسُولِهِۦ وَلَا يَأۡتُونَ ٱلصَّلَوٰةَ إِلَّا وَهُمۡ كُسَالَىٰ وَلَا يُنفِقُونَ إِلَّا وَهُمۡ كَٰرِهُونَ ٥٤","وما منعهم أن تقبل منهم نفقاتهم إلا أنهم كفروا بالله وبرسوله ولا يأتون الصلاة إلا وهم كسالى ولا ينفقون إلا وهم كارهون","އަދި ހަމަކަށަވަރުން، އެއުރެން ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް ކާފިރު ވިކަމާއި، އެއުރެން ކަންނެތްބަޔަކު ކަމުގައި ތިބެގެން މެނުވީ، ނަމާދަށް ނާންނަކަމާއި، ނުރުހިތިބި ބަޔަކު ކަމުގައިވާ ޙާލުގައި މެނުވީ، ހޭދަނުކުރާކަމާއި، މިކަންކަން ފިޔަވައި އެއުރެންގެ ހޭދަތައް އެއުރެންގެ ކިބައިން ގަބޫލުކުރެއްވުން މަނާކުރާކަމެއް ނެތެވެ.","",""],["₉ سورة التوبة","55","فَلَا تُعۡجِبۡكَ أَمۡوَٰلُهُمۡ وَلَآ أَوۡلَٰدُهُمۡۚ إِنَّمَا يُرِيدُ ٱللَّهُ لِيُعَذِّبَهُم بِهَا فِي ٱلۡحَيَوٰةِ ٱلدُّنۡيَا وَتَزۡهَقَ أَنفُسُهُمۡ وَهُمۡ كَٰفِرُونَ ٥٥","فلا تعجبك أموالهم ولا أولادهم إنما يريد الله ليعذبهم بها في الحياة الدنيا وتزهق أنفسهم وهم كافرون","އެއުރެންގެ މުދާތަކާއި، އެއުރެންގެ ދަރިންތައް ކަލޭގެފާނު އަޖާއިބުކުރުވިޔަ ނުދޭހުށިކަމެވެ! ހަމަކަށަވަރުން، ﷲ އިރާދަކުރައްވަނީ، ދުނިޔޭގެ ދިރިއުޅުމުގައި، އެތަކެތިން އެއުރެންނަށް އަޒާބު ދެއްވުމަށެވެ. އަދި އެއުރެން ކާފިރުން ކަމުގައިވާ ޙާލު، އެއުރެންގެ ފުރާނަ ދިޔުމަށެވެ.","",""],["₉ سورة التوبة","56","وَيَحۡلِفُونَ بِٱللَّهِ إِنَّهُمۡ لَمِنكُمۡ وَمَا هُم مِّنكُمۡ وَلَٰكِنَّهُمۡ قَوۡمٞ يَفۡرَقُونَ ٥٦","ويحلفون بالله إنهم لمنكم وما هم منكم ولكنهم قوم يفرقون","ހަމަކަށަވަރުން، އެއުރެންނީ، ތިޔަބައިމީހުންގެ ތެރެއިންވާ ބަޔަކު ކަމަށް، ﷲ ގަންދީ އެއުރެން ހުވާކުރާނެތެވެ. އެއުރެންނީ، ތިޔަބައިމީހުންގެ ތެރެއިންވާ ބަޔަކު ކަމުގައި ނުވެތެވެ. އެހެނެއްކަމަކު އެއުރެންނީ ބިރުގަންނަ ބަޔެކެވެ.","",""],["₉ سورة التوبة","57","لَوۡ يَجِدُونَ مَلۡجَـًٔا أَوۡ مَغَٰرَٰتٍ أَوۡ مُدَّخَلٗا لَّوَلَّوۡاْ إِلَيۡهِ وَهُمۡ يَجۡمَحُونَ ٥٧","لو يجدون ملجأ أو مغارات أو مدخلا لولوا إليه وهم يجمحون","އެއުރެން ފިލަންދާނޭ ކިއްލާއެއް، ނުވަތަ ހޮހަޅަތަކެއް، ނުވަތަ ވަންނާނޭ އެހެންތަނެއްވެސް، އެއުރެންނަށް ފެންނާނޭނަމަ، އަވަސްވެގަނެގެން އެތަނަކަށް އެއުރެން އެނބުރި ހިނގައްޖައީހެވެ.","",""],["₉ سورة التوبة","58","وَمِنۡهُم مَّن يَلۡمِزُكَ فِي ٱلصَّدَقَٰتِ فَإِنۡ أُعۡطُواْ مِنۡهَا رَضُواْ وَإِن لَّمۡ يُعۡطَوۡاْ مِنۡهَآ إِذَا هُمۡ يَسۡخَطُونَ ٥٨","ومنهم من يلمزك في الصدقات فإن أعطوا منها رضوا وإن لم يعطوا منها إذا هم يسخطون","ސަދަގާތް ބެއްސެވުމާމެދު، ކަލޭގެފާނަށް ކުޑައިމީސްބަސް ބުނާ މީހުން އެއުރެންގެ ތެރެއިންވެއެވެ. ފަހެ، އެއިން، އެއުރެންނަށް ދެއްވައިފިނަމަ، އެއުރެން ރުހެތެވެ. އެއިން އެއުރެންނަށް ނުދެއްވައިފިނަމަ، އެހާރުން އެއުރެން ރުޅި އަރަތެވެ.","",""],["₉ سورة التوبة","59","وَلَوۡ أَنَّهُمۡ رَضُواْ مَآ ءَاتَىٰهُمُ ٱللَّهُ وَرَسُولُهُۥ وَقَالُواْ حَسۡبُنَا ٱللَّهُ سَيُؤۡتِينَا ٱللَّهُ مِن فَضۡلِهِۦ وَرَسُولُهُۥٓ إِنَّآ إِلَى ٱللَّهِ رَٰغِبُونَ ٥٩","ولو أنهم رضوا ما آتاهم الله ورسوله وقالوا حسبنا الله سيؤتينا الله من فضله ورسوله إنا إلى الله راغبون","ﷲއާއި، އެކަލާނގެ ރަސޫލާ އެއުރެންނަށް ދެއްވި ތަކެއްޗަށް އެއުރެން ރުހި، އަދި އެއުރެން ބުނިނަމައެވެ. ﷲ، ތިމަންމެންނަށް ފުދެއެވެ. ﷲއާއި، އެކަލާނގެ ރަސޫލާ، އެކަލާނގެ ފަޟްލު ވަންތަކަމުގެ ތެރެއިން ތިމަންމެންނަށް ދެއްވާނެތެވެ. ހަމަކަށަވަރުން، ތިމަންމެންވަނީ، ﷲގެ ހަޒުރަތަށް އެދިއެދި ތިބޭ ބަޔަކު ކަމުގައެވެ.","",""],["₉ سورة التوبة","60","۞إِنَّمَا ٱلصَّدَقَٰتُ لِلۡفُقَرَآءِ وَٱلۡمَسَٰكِينِ وَٱلۡعَٰمِلِينَ عَلَيۡهَا وَٱلۡمُؤَلَّفَةِ قُلُوبُهُمۡ وَفِي ٱلرِّقَابِ وَٱلۡغَٰرِمِينَ وَفِي سَبِيلِ ٱللَّهِ وَٱبۡنِ ٱلسَّبِيلِۖ فَرِيضَةٗ مِّنَ ٱللَّهِۗ وَٱللَّهُ عَلِيمٌ حَكِيمٞ ٦٠","إنما الصدقات للفقراء والمساكين والعاملين عليها والمؤلفة قلوبهم وفي الرقاب والغارمين وفي سبيل الله وابن السبيل فريضة من الله والله عليم حكيم","ހަމަކަށަވަރުން، ސަދަގާތްގެ ތަކެތި ވަނީ ފަގީރުންނަށާއި، މިސްކީނުންނަށާއި، އެކަމުގެ ޢާމިލްންނަށާއި، އެއުރެންގެ ހިތްތައް އެކުވެރިކުރައްވާ މީހުންނަށާއި، (އެބަހީ: އަލަށް އިސްލާމް ވީ މީހުންނަށާއި) އަޅުން މިނިވަންކުރުމުގައްޔާއި، ދަރަނިވެރިންނަށާއި، ﷲގެ މަގުގައްޔާއި (ޙާލުގައި ޖެހިފައިވާ) ދަތުރުވެރިންނަށެވެ. ﷲގެ ހަޒުރަތުން ކަނޑައަޅުއްވާފައިވާ ފަރުޟެއްގެ ގޮތުގައެވެ. ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","61","وَمِنۡهُمُ ٱلَّذِينَ يُؤۡذُونَ ٱلنَّبِيَّ وَيَقُولُونَ هُوَ أُذُنٞۚ قُلۡ أُذُنُ خَيۡرٖ لَّكُمۡ يُؤۡمِنُ بِٱللَّهِ وَيُؤۡمِنُ لِلۡمُؤۡمِنِينَ وَرَحۡمَةٞ لِّلَّذِينَ ءَامَنُواْ مِنكُمۡۚ وَٱلَّذِينَ يُؤۡذُونَ رَسُولَ ٱللَّهِ لَهُمۡ عَذَابٌ أَلِيمٞ ٦١","ومنهم الذين يؤذون النبي ويقولون هو أذن قل أذن خير لكم يؤمن بالله ويؤمن للمؤمنين ورحمة للذين آمنوا منكم والذين يؤذون رسول الله لهم عذاب أليم","ނަބިއްޔާއަށް އުނދަގޫކުރާ މީހުން، އެއުރެންގެ ތެރެއިންވެއެވެ. އަދި އެއުރެން ބުނެތެވެ. އެކަލޭގެފާނީ، ހަމައެކަނި އައްސަވާ ބޭކަލެކެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއީ ތިޔަބައިމީހުންނަށްޓަކައި، ހެޔޮބަސް އައްސަވާ ނަބިއްޔެކެވެ. އެ ނަބިއްޔާ، ﷲއަށް އީމާންވެ ވަޑައިގަނެތެވެ. އަދި މުއުމިނުންގެ ބަސް ތެދުކުރައްވަތެވެ. އަދި އެ ނަބިއްޔާއީ، ތިޔަބައިމީހުންގެ ތެރެއިން އީމާންވި މީހުންނަށްވާ ރަހުމަތެކެވެ. އަދި ﷲގެ ރަސޫލާއަށް އުނގަދޫކުރާ މީހުންނަށް، ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["₉ سورة التوبة","62","يَحۡلِفُونَ بِٱللَّهِ لَكُمۡ لِيُرۡضُوكُمۡ وَٱللَّهُ وَرَسُولُهُۥٓ أَحَقُّ أَن يُرۡضُوهُ إِن كَانُواْ مُؤۡمِنِينَ ٦٢","يحلفون بالله لكم ليرضوكم والله ورسوله أحق أن يرضوه إن كانوا مؤمنين","އެއުރެން ތިޔަބައިމީހުން ރުއްސުމަށްޓަކައި، ﷲ ގަންދީ ތިޔަބައިމީހުން ކައިރީގައި ހުވާކޮށް ހަދަތެވެ. އެއުރެންނީ، މުއުމިނުން ކަމުގައި ވާނަމަ، އެއުރެންނަށް ހައްގު ކަން ބޮޑީ، ﷲއާއި، އެކަލާނގެ ރަސޫލާ ރުއްސުމެވެ.","",""],["₉ سورة التوبة","63","أَلَمۡ يَعۡلَمُوٓاْ أَنَّهُۥ مَن يُحَادِدِ ٱللَّهَ وَرَسُولَهُۥ فَأَنَّ لَهُۥ نَارَ جَهَنَّمَ خَٰلِدٗا فِيهَاۚ ذَٰلِكَ ٱلۡخِزۡيُ ٱلۡعَظِيمُ ٦٣","ألم يعلموا أنه من يحادد الله ورسوله فأن له نار جهنم خالدا فيها ذلك الخزي العظيم","ހަމަކަށަވަރުން، ﷲއާއި، އެކަލާނގެ ރަސޫލާއަށް ދެކޮޅުވެރިވާ މީހާ، ފަހެ، އެތާނގައި ދެމިހުންނަ ގޮތުގައި، އެމީހާއަށް ނަރަކައިގެ އަލިފާން ހުރިކަން އެއުރެން ނުދަންނަނީ ހެއްޔެވެ؟ ބޮޑުވެގެންވާ ނިކަމެތިކަމަކީ އެއީއެވެ.","",""],["₉ سورة التوبة","64","يَحۡذَرُ ٱلۡمُنَٰفِقُونَ أَن تُنَزَّلَ عَلَيۡهِمۡ سُورَةٞ تُنَبِّئُهُم بِمَا فِي قُلُوبِهِمۡۚ قُلِ ٱسۡتَهۡزِءُوٓاْ إِنَّ ٱللَّهَ مُخۡرِجٞ مَّا تَحۡذَرُونَ ٦٤","يحذر المنافقون أن تنزل عليهم سورة تنبئهم بما في قلوبهم قل استهزئوا إن الله مخرج ما تحذرون","މުނާފިގުން އެއުރެންގެ ހިތްތަކުގައިވާގޮތުގެ ޚަބަރުތައް އަންގައިދޭ ސޫރަތެއް، އެއުރެންނާމެދު ބާވައިލައްވައިފާނެތީ ބިރުގަނެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ފުރައްސާރަކޮށް އުޅޭށެވެ! ހަމަކަށަވަރުން ތިޔަބައިމީހުން ބިރުގަންނަ ކަންތައް، ﷲ ނެރުއްވައި ހާމަކުރައްވާ ހުށްޓެވެ.","",""],["₉ سورة التوبة","65","وَلَئِن سَأَلۡتَهُمۡ لَيَقُولُنَّ إِنَّمَا كُنَّا نَخُوضُ وَنَلۡعَبُۚ قُلۡ أَبِٱللَّهِ وَءَايَٰتِهِۦ وَرَسُولِهِۦ كُنتُمۡ تَسۡتَهۡزِءُونَ ٦٥","ولئن سألتهم ليقولن إنما كنا نخوض ونلعب قل أبالله وآياته ورسوله كنتم تستهزئون","ހަމަކަވަރުން، ކަލޭގެފާނު، އެއުރެންނާ ސުވާލުކުރައްވައިފިނަމަ، އެއުރެން ދަންނަވާނެކަން ކަށަވަރެވެ. ހަމަކަށަވަރުން، ތިމަންމެން ހަމައެކަނި ވާހަކަދައްކާލައި، ކުޅިވަރު ކުޅޭކަމުގައި ވީމުއެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ތިޔަ މަލާމާތްކޮށް އުޅުނީ، ﷲއާއި، އެކަލާނގެ އާޔަތް ތަކާއި، އެކަލާނގެ ރަސޫލާއަށް ހެއްޔެވެ؟","",""],["₉ سورة التوبة","66","لَا تَعۡتَذِرُواْ قَدۡ كَفَرۡتُم بَعۡدَ إِيمَٰنِكُمۡۚ إِن نَّعۡفُ عَن طَآئِفَةٖ مِّنكُمۡ نُعَذِّبۡ طَآئِفَةَۢ بِأَنَّهُمۡ كَانُواْ مُجۡرِمِينَ ٦٦","لا تعتذروا قد كفرتم بعد إيمانكم إن نعف عن طائفة منكم نعذب طائفة بأنهم كانوا مجرمين","ތިޔަބައިމީހުން އުޒުރު ނުދައްކާށެވެ! ތިޔަބައިމީހުން އީމާން ވުމަށްފަހު، ތިޔަބައިމީހުން ތިޔަތިބީ ކާފިރު ވެފައިކަން ކަށަވަރެވެ. ތިޔަބައިމީހުންގެ ތެރެއިން ބަޔަކަށް ތިމަންރަސްކަލާނގެ އަފޫކުރެއްވިޔަސް، އަނެއްބަޔަކަށް ތިމަންރަސްކަލާނގެ އަޒާބު ދެއްވަމެވެ. އެއީ ހަމަކަށަވަރުން، އެއުރެން ކުށްވެރި ބަޔަކު ކަމުގައި ވީކަމަށްޓަކައެވެ.","",""],["₉ سورة التوبة","67","ٱلۡمُنَٰفِقُونَ وَٱلۡمُنَٰفِقَٰتُ بَعۡضُهُم مِّنۢ بَعۡضٖۚ يَأۡمُرُونَ بِٱلۡمُنكَرِ وَيَنۡهَوۡنَ عَنِ ٱلۡمَعۡرُوفِ وَيَقۡبِضُونَ أَيۡدِيَهُمۡۚ نَسُواْ ٱللَّهَ فَنَسِيَهُمۡۚ إِنَّ ٱلۡمُنَٰفِقِينَ هُمُ ٱلۡفَٰسِقُونَ ٦٧","المنافقون والمنافقات بعضهم من بعض يأمرون بالمنكر وينهون عن المعروف ويقبضون أيديهم نسوا الله فنسيهم إن المنافقين هم الفاسقون","މުނާފިގު ފިރިހެނުންނާއި، މުނާފިގު އަންހެނުންނީ، އޭގެ އެއްބަޔަކު އަނެއްބަޔެއްގެ ތެރެއިންވާ ބަޔެކެވެ. އެއުރެން ނުބައިކަންތަކަށް އަމުރުކުރެތެވެ. އަދި އެއުރެން ހެޔޮކަންތައް ނަހީކުރެތެވެ. އަދި އެއުރެންގެ އަތްތައް ލައްޕަތެވެ. (އެބަހީ، ހޭދަކުރުމުން އެއްކިބާވެ، މުށްބާރުކުރެތެވެ.) އެއުރެން، ﷲ ހަނދުމަނެތި ކުރޫއެވެ. ދެން ﷲއެއުރެންގެ މަތިން ހަނދުމަނެތި ކުރެއްވިއެވެ. ހަމަކަށަވަރުން، މުނާފިގުންނަކީ، ހަމަ ފާސިގުންނެވެ.","",""],["₉ سورة التوبة","68","وَعَدَ ٱللَّهُ ٱلۡمُنَٰفِقِينَ وَٱلۡمُنَٰفِقَٰتِ وَٱلۡكُفَّارَ نَارَ جَهَنَّمَ خَٰلِدِينَ فِيهَاۚ هِيَ حَسۡبُهُمۡۚ وَلَعَنَهُمُ ٱللَّهُۖ وَلَهُمۡ عَذَابٞ مُّقِيمٞ ٦٨","وعد الله المنافقين والمنافقات والكفار نار جهنم خالدين فيها هي حسبهم ولعنهم الله ولهم عذاب مقيم","މުނާފިގު ފިރިހެނުންނާއި، މުނާފިގު އަންހެނުންނާއި، ކާފިރުންނަށް ﷲ ވައުދުކުރައްވާފައިވަނީ، ނަރަކައިގެ އަލިފާނެވެ. އެތާނގައި އެއުރެން ދެމިތިބޭ ޙާލު ގައެވެ. އެ ނަރަކަ އެއުރެންނަށް ފުދިގެންވެއެވެ. އަދި ﷲއެއުރެންނަށް ލައުނަތް ލެއްވިއެވެ. އަދި ދެމިހުންނަނިވި އަޒާބެއުރެންނަށް ހުށްޓެވެ.","",""],["₉ سورة التوبة","69","كَٱلَّذِينَ مِن قَبۡلِكُمۡ كَانُوٓاْ أَشَدَّ مِنكُمۡ قُوَّةٗ وَأَكۡثَرَ أَمۡوَٰلٗا وَأَوۡلَٰدٗا فَٱسۡتَمۡتَعُواْ بِخَلَٰقِهِمۡ فَٱسۡتَمۡتَعۡتُم بِخَلَٰقِكُمۡ كَمَا ٱسۡتَمۡتَعَ ٱلَّذِينَ مِن قَبۡلِكُم بِخَلَٰقِهِمۡ وَخُضۡتُمۡ كَٱلَّذِي خَاضُوٓاْۚ أُوْلَـٰٓئِكَ حَبِطَتۡ أَعۡمَٰلُهُمۡ فِي ٱلدُّنۡيَا وَٱلۡأٓخِرَةِۖ وَأُوْلَـٰٓئِكَ هُمُ ٱلۡخَٰسِرُونَ ٦٩","كالذين من قبلكم كانوا أشد منكم قوة وأكثر أموالا وأولادا فاستمتعوا بخلاقهم فاستمتعتم بخلاقكم كما استمتع الذين من قبلكم بخلاقهم وخضتم كالذي خاضوا أولئك حبطت أعمالهم في الدنيا والآخرة وأولئك هم الخاسرون","(ތިޔަބައިމީހުން) ތިޔަބައިމީހުންގެ ކުރީގެ މީހުން ފަދައެވެ. އެއުރެން ތިޔަބައިމީހުންނަށްވުރެ ބާރުގަދަ ބަޔަކު ކަމުގައި، އަދި މުދާތަކާއި، ދަރިންތައް ގިނަބަޔަކު ކަމުގައިވިއެވެ. ފަހެ (ދުނިޔެއިން) އެއުރެންގެ ނަސީބުން އެއުރެން އަރާމު ލިބިގަތެވެ. ފަހެ، ތިޔަބައިމީހުންވެސް ތިޔަބައިމީހުންގެ ކުރީގެ މީހުން އެއުރެންގެ ނަސީބުން އަރާމު ލިބިގަތްފަދައިން، ތިޔަބައިމީހުންގެ ނަސީބުން އަރާމު ލިބިގެންފީމުއެވެ. އަދި ބާތިލު ވާހަކަތައް އެއުރެން ދައްކަމުން ދިޔަފަދައިން، ތިޔަބައިމީހުންވެސް ބާތިލު ވާހަކަތައް ދައްކަމުން ދިޔައީމުއެވެ. އެއުރެންނީ، ދުނިޔެއާއި އާޚިރަތުގައި، އެއުރެންގެ ޢަމަލުތައް ބާތިލު ވެގެންވާ މީހުންނެވެ. އަދި ހަމަ، އެއުރެންނީ، ގެއްލެނިވެގެންވާ މީހުންނެވެ.","",""],["₉ سورة التوبة","70","أَلَمۡ يَأۡتِهِمۡ نَبَأُ ٱلَّذِينَ مِن قَبۡلِهِمۡ قَوۡمِ نُوحٖ وَعَادٖ وَثَمُودَ وَقَوۡمِ إِبۡرَٰهِيمَ وَأَصۡحَٰبِ مَدۡيَنَ وَٱلۡمُؤۡتَفِكَٰتِۚ أَتَتۡهُمۡ رُسُلُهُم بِٱلۡبَيِّنَٰتِۖ فَمَا كَانَ ٱللَّهُ لِيَظۡلِمَهُمۡ وَلَٰكِن كَانُوٓاْ أَنفُسَهُمۡ يَظۡلِمُونَ ٧٠","ألم يأتهم نبأ الذين من قبلهم قوم نوح وعاد وثمود وقوم إبراهيم وأصحاب مدين والمؤتفكات أتتهم رسلهم بالبينات فما كان الله ليظلمهم ولكن كانوا أنفسهم يظلمون","އެއުރެންގެ ކުރީގެ މީހުންގެ ޚަބަރު، އެއުރެންނާ ހަމަޔަށް ނާންނަނީހެއްޔެވެ؟ (އެއީ) ނޫޙުގެފާނުގެ ގައުމުގެމީހުންނާއި، ޢާދު ބާގައިމީހުންނާއި، ޘަމޫދު ބާގައިމީހުންނާއި، އިބްރާހީމްގެފާނުގެ ގައުމުގެމީހުންނާއި، މަދްޔަންގެ އަހުލުވެރިންނާއި، ބަންޑުންޖެއްސެވި ރަށްތަކުގެ އަހުލުވެރިންގެ ޚަބަރެވެ. އެއުރެންގެ ރަސޫލުން އެއުރެންގެ ގާތަށް ފާޅުވެގެންވާ ހެކިތަކާއިގެން ވަޑައިގެންނެވިއެވެ. ފަހެ، ﷲއެއުރެންނަށް އަނިޔާކުރައްވާ ކަލަކުކަމުގައި ނުވެއެވެ. އެހެނެއްކަމަކު، އެއުރެން، އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް އަނިޔާކުރާ ކަމުގައި ވިއެވެ.","",""],["₉ سورة التوبة","71","وَٱلۡمُؤۡمِنُونَ وَٱلۡمُؤۡمِنَٰتُ بَعۡضُهُمۡ أَوۡلِيَآءُ بَعۡضٖۚ يَأۡمُرُونَ بِٱلۡمَعۡرُوفِ وَيَنۡهَوۡنَ عَنِ ٱلۡمُنكَرِ وَيُقِيمُونَ ٱلصَّلَوٰةَ وَيُؤۡتُونَ ٱلزَّكَوٰةَ وَيُطِيعُونَ ٱللَّهَ وَرَسُولَهُۥٓۚ أُوْلَـٰٓئِكَ سَيَرۡحَمُهُمُ ٱللَّهُۗ إِنَّ ٱللَّهَ عَزِيزٌ حَكِيمٞ ٧١","والمؤمنون والمؤمنات بعضهم أولياء بعض يأمرون بالمعروف وينهون عن المنكر ويقيمون الصلاة ويؤتون الزكاة ويطيعون الله ورسوله أولئك سيرحمهم الله إن الله عزيز حكيم","މުއުމިނު ފިރިހެނުންނާއި، މުއުމިނު އަންހެނުންނީ، އޭގެ އެއްބަޔަކު އަނެއްބަޔެއްގެ އެހީތެރިން ކަމުގައިވާ މީހުންނެވެ. އެއުރެން ހެޔޮކަންތަކަށް އަމުރުކުރެތެވެ. އަދި އެއުރެން ނުބައިކަންތައް ނަހީކުރެތެވެ. އަދި އެއުރެން ނަމާދު ގާއިމު ކޮށް، ޒަކާތް ދީ، ﷲއާއި އެކަލާނގެ ރަސޫލާއަށް ކިޔަމަންވެތެވެ. އެއުރެންނަށް ﷲ ރަހުމަތް ލައްވާހުށްޓެވެ. ހަމަކަށަވަރުން، ﷲއީ، ޢަޒީޒުވަންތަ ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","72","وَعَدَ ٱللَّهُ ٱلۡمُؤۡمِنِينَ وَٱلۡمُؤۡمِنَٰتِ جَنَّـٰتٖ تَجۡرِي مِن تَحۡتِهَا ٱلۡأَنۡهَٰرُ خَٰلِدِينَ فِيهَا وَمَسَٰكِنَ طَيِّبَةٗ فِي جَنَّـٰتِ عَدۡنٖۚ وَرِضۡوَٰنٞ مِّنَ ٱللَّهِ أَكۡبَرُۚ ذَٰلِكَ هُوَ ٱلۡفَوۡزُ ٱلۡعَظِيمُ ٧٢","وعد الله المؤمنين والمؤمنات جنات تجري من تحتها الأنهار خالدين فيها ومساكن طيبة في جنات عدن ورضوان من الله أكبر ذلك هو الفوز العظيم","މުއުމިނު ފިރިހެނުންނާއި، މުއުމިނު އަންހެނުންނަށް، ﷲ ވައުދުކުރައްވާފައިވަނީ އެތާނގެ ދަށުން ކޯރުތައް ހިނގައިހިނގާ ހުންނަ ސުވަރުގެތަކެވެ. އެތަންތާނގައި، އެއުރެން ދެމިތިބޭ ގޮތުގައެވެ. އަދި ޢަދަނެވެ ކިއުނު ސުވަރުގެތަކުގައި ތިބޭނޭ ރަނގަޅު ގޮވަތިގެދޮރުވެސް މެއެވެ. އަދި ﷲގެ ހަޒުރަތުން ލިބޭ ރުއްސެވުން މާބޮޑެވެ. ބޮޑުވެގެންވާ ނަސީބު ލިބުމަކީ ހަމަ އެއީއެވެ.","",""],["₉ سورة التوبة","73","يَـٰٓأَيُّهَا ٱلنَّبِيُّ جَٰهِدِ ٱلۡكُفَّارَ وَٱلۡمُنَٰفِقِينَ وَٱغۡلُظۡ عَلَيۡهِمۡۚ وَمَأۡوَىٰهُمۡ جَهَنَّمُۖ وَبِئۡسَ ٱلۡمَصِيرُ ٧٣","يا أيها النبي جاهد الكفار والمنافقين واغلظ عليهم ومأواهم جهنم وبئس المصير","އޭ ނަބިއްޔާއެވެ! ކާފިރްނާއި، މުނާފިގުންނާ ދެކޮޅަށް ކަލޭގެފާނު ޖިހާދުކުރައްވާށެވެ! އަދި އެއުރެންގެ މައްޗަށް ކަލޭގެފާނު ހަރުކަށިވެ ވަޑައިގަންނަވާށެވެ! އަދި (އާޚިރަތް ދުވަހުން) އެއުރެން ތިބެނިވި ތަނަކީ ނަރަކައެވެ. އަދި (އެއީ) ހާދަހާ ނުބައިވެގެންވާ ނިމިދިޔުމެކެވެ.","",""],["₉ سورة التوبة","74","يَحۡلِفُونَ بِٱللَّهِ مَا قَالُواْ وَلَقَدۡ قَالُواْ كَلِمَةَ ٱلۡكُفۡرِ وَكَفَرُواْ بَعۡدَ إِسۡلَٰمِهِمۡ وَهَمُّواْ بِمَا لَمۡ يَنَالُواْۚ وَمَا نَقَمُوٓاْ إِلَّآ أَنۡ أَغۡنَىٰهُمُ ٱللَّهُ وَرَسُولُهُۥ مِن فَضۡلِهِۦۚ فَإِن يَتُوبُواْ يَكُ خَيۡرٗا لَّهُمۡۖ وَإِن يَتَوَلَّوۡاْ يُعَذِّبۡهُمُ ٱللَّهُ عَذَابًا أَلِيمٗا فِي ٱلدُّنۡيَا وَٱلۡأٓخِرَةِۚ وَمَا لَهُمۡ فِي ٱلۡأَرۡضِ مِن وَلِيّٖ وَلَا نَصِيرٖ ٧٤","يحلفون بالله ما قالوا ولقد قالوا كلمة الكفر وكفروا بعد إسلامهم وهموا بما لم ينالوا وما نقموا إلا أن أغناهم الله ورسوله من فضله فإن يتوبوا يك خيرا لهم وإن يتولوا يعذبهم الله عذابا أليما في الدنيا والآخرة وما لهم في الأرض من ولي ولا نصير","އެއުރެން (ބުނި ނުބައި ބަސްތައް) ނުބުނާކަމަށް، ﷲ ގަންދީ އެއުރެން ހުވާކުރެތެވެ. ހަމަކަށަވަރުން، ކުފުރުގެ ބަސް އެއުރެން ބުނެފައިވެއެވެ. އަދި އިސްލާމް ވުމަށްފަހު، އެއުރެން ކާފިރު ވިއެވެ. އަދި އެއުރެންނަށް ކާމިޔާބު ނުކުރެވުނު ކަންތައް ކުރުމަށް (އެބަހީ: ރާވައިގެން ކީރިތި ރަސޫލާ އަވަހާރަކޮށްލުމަށް) ގަސްދުކޮށް އުޅުނޫވެ. ﷲގެ ފަޟްލު ވަންތަކަމުން، ﷲއާއި، އެކަލާނގެ ރަސޫލާ، އެއުރެން (އެބަހީ: މުއުމިނުން) މުއްސަނދި ކޮށްދެއްވިކަން ނޫން އެހެން ކަމަކާމެދު އެއުރެން ރުޅިއެއް ނާދެތެވެ. ފަހެ، އެއުރެން ތައުބާ ވާނަމަ، އެއުރެންނަށް އެގޮތް ހެޔޮކަން ބޮޑުވެގެންވެއެވެ. އަދި އެއުރެން އެނބުރި ފުރަގަސްދޭނަމަ، ދުނިޔެއާއި، އާޚިރަތުގައި ވޭންދެނިވި އަޒާބަކުން، ﷲއެއުރެންނަށް އަޒާބު ދެއްވާނެތެވެ. އަދި ބިމުގައި އެއުރެންނަށް އެއްވެސް އެހީތެރިޔަކު، އަދި ނަސްރު ދޭނޭ މީހަކުވެސް ނުވެއެވެ.","",""],["₉ سورة التوبة","75","۞وَمِنۡهُم مَّنۡ عَٰهَدَ ٱللَّهَ لَئِنۡ ءَاتَىٰنَا مِن فَضۡلِهِۦ لَنَصَّدَّقَنَّ وَلَنَكُونَنَّ مِنَ ٱلصَّـٰلِحِينَ ٧٥","ومنهم من عاهد الله لئن آتانا من فضله لنصدقن ولنكونن من الصالحين","ހަމަކަށަވަރުން، އެކަލާނގެ ފަޟްލު ވަންތަކަމުގެ ތެރެއިން ތިމަންމެންނަށް ދެއްވައިފިނަމަ، ހަމަކަށަވަރުން، ތިމަންމެން ސަދަގާތްކުރާ ހުށީމުއޭ، އަދި ހަމަކަށަވަރުން، ތިމަންމެން ސާލިހުންގެ ތެރެއިން ވާހުށީމުއޭ ކިޔައި، ﷲއަށް އަހުދު ކޮށް އުޅުނު މީހުންވެސް، އެއުރެންގެ ތެރެއިން ވެތެވެ.","",""],["₉ سورة التوبة","76","فَلَمَّآ ءَاتَىٰهُم مِّن فَضۡلِهِۦ بَخِلُواْ بِهِۦ وَتَوَلَّواْ وَّهُم مُّعۡرِضُونَ ٧٦","فلما آتاهم من فضله بخلوا به وتولوا وهم معرضون","ފަހެ، އެކަލާނގެ ފަޟްލު ވަންތަކަމުގެ ތެރެއިން، އެއުރެންނަށް ދެއްވިހިނދު، އެތަކެއްޗަށް އެއުރެން ދަހިވެތިވޫއެވެ. އަދި އެއުރެން ފުރަގަސްދޭ ޙާލު، އެނބުރި ދިޔައޫއެވެ.","",""],["₉ سورة التوبة","77","فَأَعۡقَبَهُمۡ نِفَاقٗا فِي قُلُوبِهِمۡ إِلَىٰ يَوۡمِ يَلۡقَوۡنَهُۥ بِمَآ أَخۡلَفُواْ ٱللَّهَ مَا وَعَدُوهُ وَبِمَا كَانُواْ يَكۡذِبُونَ ٧٧","فأعقبهم نفاقا في قلوبهم إلى يوم يلقونه بما أخلفوا الله ما وعدوه وبما كانوا يكذبون","ދެން އެކަމާވިދިގެން އެކަލާނގެ އެއުރެންގެ ހިތްތަކުގައި ނިފާގު ކަން ލެއްވިއެވެ. އެކަލާނގެއާ އެއުރެން ބައްދަލުކުރާ ދުވަހަށް ދާނދެނެވެ. (އެއީ) އެއުރެން ﷲއަށް ވައުދުކުރި ކަންތަކާމެދު، ﷲއަށް އެއުރެން ޚިލާފު ވީކަމަށްޓަކައެވެ. އަދި އެއުރެން ދޮގުހަދައި އުޅުނުކަމަށްޓަކައެވެ.","",""],["₉ سورة التوبة","78","أَلَمۡ يَعۡلَمُوٓاْ أَنَّ ٱللَّهَ يَعۡلَمُ سِرَّهُمۡ وَنَجۡوَىٰهُمۡ وَأَنَّ ٱللَّهَ عَلَّـٰمُ ٱلۡغُيُوبِ ٧٨","ألم يعلموا أن الله يعلم سرهم ونجواهم وأن الله علام الغيوب","ހަމަކަށަވަރުން، އެއުރެންގެ (ހިތްތަކުގައިވާ) ސިއްރުތަކާއި، އެއުރެންގެ ސިއްރު ސައްލާތައް ﷲ ދެނެވޮޑިގެންވާކަމާއި، ހަމަކަށަވަރުން، ﷲއީ، ޣައިބުތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެކަން އެއުރެން ނުދަންނަނީ ހެއްޔެވެ؟","",""],["₉ سورة التوبة","79","ٱلَّذِينَ يَلۡمِزُونَ ٱلۡمُطَّوِّعِينَ مِنَ ٱلۡمُؤۡمِنِينَ فِي ٱلصَّدَقَٰتِ وَٱلَّذِينَ لَا يَجِدُونَ إِلَّا جُهۡدَهُمۡ فَيَسۡخَرُونَ مِنۡهُمۡ سَخِرَ ٱللَّهُ مِنۡهُمۡ وَلَهُمۡ عَذَابٌ أَلِيمٌ ٧٩","الذين يلمزون المطوعين من المؤمنين في الصدقات والذين لا يجدون إلا جهدهم فيسخرون منهم سخر الله منهم ولهم عذاب أليم","އެއުރެންނީ، މުއުމިނުންގެ ތެރެއިން ތަޠައްވުޢުގެ ގޮތުން ސަދަގާތް ދޭ މީހުންގެ ސަދަގާތާމެދު، ކުޑައިމީސްބަސް ބުނާ މީހުންނެވެ. އަދި އެއުރެންނީ (އެބަހީ: މުއުމިނުންނީ) އެއުރެންނަށް ކިރިޔާ ފުދޭމިންވަރު ނޫނީ ނުލިބޭ މީހުންނެވެ. ފަހެ، އެއުރެންނަށް އެއުރެން (އެބަހީ: މުނާފިގުން) މަލާމާތް ކުރެތެވެ. ﷲއެއުރެންނަށް މަލާމާތް ރައްދުކުރެއްވިއެވެ. އަދި އެއުރެންނަށް ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["₉ سورة التوبة","80","ٱسۡتَغۡفِرۡ لَهُمۡ أَوۡ لَا تَسۡتَغۡفِرۡ لَهُمۡ إِن تَسۡتَغۡفِرۡ لَهُمۡ سَبۡعِينَ مَرَّةٗ فَلَن يَغۡفِرَ ٱللَّهُ لَهُمۡۚ ذَٰلِكَ بِأَنَّهُمۡ كَفَرُواْ بِٱللَّهِ وَرَسُولِهِۦۗ وَٱللَّهُ لَا يَهۡدِي ٱلۡقَوۡمَ ٱلۡفَٰسِقِينَ ٨٠","استغفر لهم أو لا تستغفر لهم إن تستغفر لهم سبعين مرة فلن يغفر الله لهم ذلك بأنهم كفروا بالله ورسوله والله لا يهدي القوم الفاسقين","އެއުރެންނަށް ފާފަފުއްސެވުމަށް ކަލޭގެފާނު އެދިވަޑައިގަންނަވާށެވެ! ނުވަތަ އެއުރެންނަށް ފާފަފުއްސެވުމަށް ކަލޭގެފާނު އެދިވަޑައިނުގަންނަވާށެވެ! އެއުރެންނަށް ފާފަފުއްސެވުމަށް ހަތްދިހަ ފަހަރު ކަލޭގެފާނު އެދިވަޑައިގަތަސް، ﷲ، އެއުރެންނަކަށް ފާފައެއް ނުފުއްސަވާނެތެވެ. އެއީ އެއުރެން ﷲއާއި އެކަލާނގެ ރަސޫލާއަށް ކާފިރުވި ކަމަށްޓަކައެވެ. އަދި ފާސިގު ވެގެންވާ ބަޔަކަށް ﷲ ތެދުމަގެއް ނުދައްކަވާނެތެވެ.","",""],["₉ سورة التوبة","81","فَرِحَ ٱلۡمُخَلَّفُونَ بِمَقۡعَدِهِمۡ خِلَٰفَ رَسُولِ ٱللَّهِ وَكَرِهُوٓاْ أَن يُجَٰهِدُواْ بِأَمۡوَٰلِهِمۡ وَأَنفُسِهِمۡ فِي سَبِيلِ ٱللَّهِ وَقَالُواْ لَا تَنفِرُواْ فِي ٱلۡحَرِّۗ قُلۡ نَارُ جَهَنَّمَ أَشَدُّ حَرّٗاۚ لَّوۡ كَانُواْ يَفۡقَهُونَ ٨١","فرح المخلفون بمقعدهم خلاف رسول الله وكرهوا أن يجاهدوا بأموالهم وأنفسهم في سبيل الله وقالوا لا تنفروا في الحر قل نار جهنم أشد حرا لو كانوا يفقهون","ފަސްޖެހުނު މީހުން، ﷲގެ ރަސޫލާއާ ޚިލާފަށް ހަނގުރާމައަށް ނުގޮސް ތިބިތިބުމަށް އުފާކުޅައޫއެވެ. އަދި ﷲގެ މަގުގައި، އެއުރެންގެ މުދާތަކާއި، ނަފްސު ތަކުން ޖިހާދުކުޅައުމަށް އެއުރެން ނުރުހުންވޫއެވެ. އަދި އެއުރެން ބުނެފޫއެވެ. ހޫނުގެ ތެރޭގައި ތިޔަބައިމީހުން ހަނގުރާމަޔަށް ނުނިކުންނާށެވެ! ކަލޭގެފާނު ވިދާޅުވާށެވެ! ނަރަކައިގެ އަލިފާނުގެ ހޫނުކަން މާގަދައެވެ. އެއުރެންނަށް (އެކަން) ވިސްނޭކަމުގައި ވާނަމައެވެ.","",""],["₉ سورة التوبة","82","فَلۡيَضۡحَكُواْ قَلِيلٗا وَلۡيَبۡكُواْ كَثِيرٗا جَزَآءَۢ بِمَا كَانُواْ يَكۡسِبُونَ ٨٢","فليضحكوا قليلا وليبكوا كثيرا جزاء بما كانوا يكسبون","ފަހެ، އެއުރެން މަދުން ހޭހުށިކަމެވެ! އަދި އެއުރެން ގިނައިން ރޯހުށިކަމެވެ! (އެއީ) އެއުރެން ހޯދައިއުޅުނު ޢަމަލުތަކުގެ ޖަޒާއެއްގެ ގޮތުގައެވެ.","",""],["₉ سورة التوبة","83","فَإِن رَّجَعَكَ ٱللَّهُ إِلَىٰ طَآئِفَةٖ مِّنۡهُمۡ فَٱسۡتَـٔۡذَنُوكَ لِلۡخُرُوجِ فَقُل لَّن تَخۡرُجُواْ مَعِيَ أَبَدٗا وَلَن تُقَٰتِلُواْ مَعِيَ عَدُوًّاۖ إِنَّكُمۡ رَضِيتُم بِٱلۡقُعُودِ أَوَّلَ مَرَّةٖ فَٱقۡعُدُواْ مَعَ ٱلۡخَٰلِفِينَ ٨٣","فإن رجعك الله إلى طائفة منهم فاستأذنوك للخروج فقل لن تخرجوا معي أبدا ولن تقاتلوا معي عدوا إنكم رضيتم بالقعود أول مرة فاقعدوا مع الخالفين","އެއުރެންގެ ތެރެއިން، ބަޔެއްގެ ގާތަށް ﷲ، ކަލޭގެފާނު އަނބުރާ ފޮނުއްވައިފިނަމަ، އަދި އެއުރެން (ހަނގުރާމަޔަށް) ނުކުތުމަށް އިޒުނަށް އެދި ކަލޭގެފާނަށް ދަންނަވައިފިނަމަ، ފަހެ، ކަލޭގެފާނު ވިދާޅުވާށެވެ! ދުވަހަކުވެސް ތިޔަބައިމީހުން، ތިމަންކަލޭގެފާނާ އެކުގައި (ހަނގުރާމަޔަށް) ނުކުމެގެން ނުވާނެއެވެ. އަދި ތިމަންކަލޭގެފާނާ އެކުގައި، ތިޔަބައިމީހުން ދުޝްމަނަކާ ހަނގުރާމަކޮށްގެން ނުވާނެއެވެ. ހަމަކަށަވަރުން، ފުރަތަމަ ފަހަރުވެސް (ހަނގުރާމަޔަށް ނުގޮސް) ތިބުމަށް، ތިޔަބައިމީހުން ރުހުނީމުއެވެ. ދެންވެސް (ހަނގުރާމަޔަށް ނުގޮސް) ފަސްޖެހިތިބޭ މީހުންނާއެކު ތިޔަބައިމީހުން ތިބޭށެވެ!","",""],["₉ سورة التوبة","84","وَلَا تُصَلِّ عَلَىٰٓ أَحَدٖ مِّنۡهُم مَّاتَ أَبَدٗا وَلَا تَقُمۡ عَلَىٰ قَبۡرِهِۦٓۖ إِنَّهُمۡ كَفَرُواْ بِٱللَّهِ وَرَسُولِهِۦ وَمَاتُواْ وَهُمۡ فَٰسِقُونَ ٨٤","ولا تصل على أحد منهم مات أبدا ولا تقم على قبره إنهم كفروا بالله ورسوله وماتوا وهم فاسقون","އެއުރެންގެ ތެރެއިން މަރުވި އެއްވެސް މީހެއްގެ މައްޗަށް ކަލޭގެފާނު ދުވަހަކުވެސް ކަށުނަމާދު ނުކުރައްވާށެވެ! އަދި އެމީހެއްގެ މަހާނަދޮށުގައިވެސް ކަލޭގެފާނު ހުއްޓިވަޑައިގެން ނުހުންނަވާށެވެ! ހަމަކަށަވަރުން، އެއުރެން ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް ކާފިރު ވޫއެވެ. އަދި އެއުރެން މަރުވީ، ފާސިގުން ކަމުގައިވާ ޙާލު ގައެވެ.","",""],["₉ سورة التوبة","85","وَلَا تُعۡجِبۡكَ أَمۡوَٰلُهُمۡ وَأَوۡلَٰدُهُمۡۚ إِنَّمَا يُرِيدُ ٱللَّهُ أَن يُعَذِّبَهُم بِهَا فِي ٱلدُّنۡيَا وَتَزۡهَقَ أَنفُسُهُمۡ وَهُمۡ كَٰفِرُونَ ٨٥","ولا تعجبك أموالهم وأولادهم إنما يريد الله أن يعذبهم بها في الدنيا وتزهق أنفسهم وهم كافرون","އަދި އެއުރެންގެ މުދާތަކާއި، އެއުރެންގެ ދަރިންތައް ކަލޭގެފާނު އަޖާއިބުކުރުވިޔަ ނުދޭހުށިކަމެވެ! ހަމަކަށަވަރުން، ﷲ އިރާދަކުރައްވަނީ، އެތަކެތީގެ ސަބަބުން، އެއުރެންނަށް، ދުނިޔޭގައި އަޒާބު ދެއްވުމަށެވެ. އަދި އެއުރެންނީ ކާފިރުން ކަމުގައިވާ ޙާލު، އެއުރެންގެ ފުރާނަތައް ނިކުމެގެން ދިއުމަށެވެ.","",""],["₉ سورة التوبة","86","وَإِذَآ أُنزِلَتۡ سُورَةٌ أَنۡ ءَامِنُواْ بِٱللَّهِ وَجَٰهِدُواْ مَعَ رَسُولِهِ ٱسۡتَـٔۡذَنَكَ أُوْلُواْ ٱلطَّوۡلِ مِنۡهُمۡ وَقَالُواْ ذَرۡنَا نَكُن مَّعَ ٱلۡقَٰعِدِينَ ٨٦","وإذا أنزلت سورة أن آمنوا بالله وجاهدوا مع رسوله استأذنك أولو الطول منهم وقالوا ذرنا نكن مع القاعدين","ތިޔަބައިމީހުން، ﷲއަށް އީމާން ވުމަށާއި، އެކަލާނގެ ރަސޫލާގެ އަރިހުގައި ޖިހާދުކުރުމަށް އަންގަވާފައިވާ ސޫރަތެއް ބާވައިލައްވައިފިނަމަ، އެއުރެންގެ ތެރެއިން ތަނަވަސްކަމާއި، ބާރުވެރިކަމުގެ އަހުލުވެރިން (ހަނގުރާމަޔަށް ނުގޮސް ތިބުމަށް) ކަލޭގެފާނުގެ އަރިހުން އިޒުނަށް އެދޭނެތެވެ. އަދި އެއުރެން ބުނާނެތެވެ. (ހަނގުރާމަޔަށް ނުގޮސް) ތިބޭ މީހުންނާއެކުގައި ވުމަށް، ތިމަންމެން ދޫކޮށްލައްވާށެވެ!","",""],["₉ سورة التوبة","87","رَضُواْ بِأَن يَكُونُواْ مَعَ ٱلۡخَوَالِفِ وَطُبِعَ عَلَىٰ قُلُوبِهِمۡ فَهُمۡ لَا يَفۡقَهُونَ ٨٧","رضوا بأن يكونوا مع الخوالف وطبع على قلوبهم فهم لا يفقهون","(ހަނގުރާމަޔަށް ނުގޮސް) ގޭގައި ތިބޭ އަންހެނުންނާ އެކުގައި ވުމަށް، އެއުރެން ރުހުނޫއެވެ. އަދި އެއުރެންގެ ހިތްތަކުގައި ސިއްކަގައްސަވައި ބަންދު ކުރައްވާފައިވެއެވެ. ފަހެ، އެއުރެންނަށް ނުވިސްނެނީއެވެ.","",""],["₉ سورة التوبة","88","لَٰكِنِ ٱلرَّسُولُ وَٱلَّذِينَ ءَامَنُواْ مَعَهُۥ جَٰهَدُواْ بِأَمۡوَٰلِهِمۡ وَأَنفُسِهِمۡۚ وَأُوْلَـٰٓئِكَ لَهُمُ ٱلۡخَيۡرَٰتُۖ وَأُوْلَـٰٓئِكَ هُمُ ٱلۡمُفۡلِحُونَ ٨٨","لكن الرسول والذين آمنوا معه جاهدوا بأموالهم وأنفسهم وأولئك لهم الخيرات وأولئك هم المفلحون","އެހެނެއްކަމަކު، ރަސޫލާއާއި، އެކަލޭގެފާނުގެ އަރިހުގައި އީމާން ވެގެން ތިބިމީހުން، އެއުރެންގެ މުދާތަކާއި، ނަފްސު ތަކުން ޖިހާދުކުރޫއެވެ. އެއުރެންނަށް ހެޔޮ ދަރުމަތައް ހުށްޓެވެ. އަދި ދިންނަވާނޭ މީހުންނަކީ ހަމަ އެއުރެންނެވެ.","",""],["₉ سورة التوبة","89","أَعَدَّ ٱللَّهُ لَهُمۡ جَنَّـٰتٖ تَجۡرِي مِن تَحۡتِهَا ٱلۡأَنۡهَٰرُ خَٰلِدِينَ فِيهَاۚ ذَٰلِكَ ٱلۡفَوۡزُ ٱلۡعَظِيمُ ٨٩","أعد الله لهم جنات تجري من تحتها الأنهار خالدين فيها ذلك الفوز العظيم","އެތާނގެ ދަށުން ކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތައް، ﷲ، އެއުރެންނަށްޓަކައި، ތައްޔާރުކުރައްވާފައިވެއެވެ. އެ ސުވަރުގެތަކުގައި އެއުރެން ދެމިތިބެނިވި ގޮތުގައެވެ. ބޮޑުވެގެންވާ ނަސީބު ލިބުމަކީ އެއީއެވެ.","",""],["₉ سورة التوبة","90","وَجَآءَ ٱلۡمُعَذِّرُونَ مِنَ ٱلۡأَعۡرَابِ لِيُؤۡذَنَ لَهُمۡ وَقَعَدَ ٱلَّذِينَ كَذَبُواْ ٱللَّهَ وَرَسُولَهُۥۚ سَيُصِيبُ ٱلَّذِينَ كَفَرُواْ مِنۡهُمۡ عَذَابٌ أَلِيمٞ ٩٠","وجاء المعذرون من الأعراب ليؤذن لهم وقعد الذين كذبوا الله ورسوله سيصيب الذين كفروا منهم عذاب أليم","އަޢުރާބީންގެ ތެރެއިން އުޒުރުވެރިވެގަންނަ މީހުން (ހަނގުރާމަޔަށް ނުގޮސް ތިބުމަށް) އެއުރެންނަށް އިޒުނަ ލިބުމަށްޓަކައި އައޫއެވެ. އަދި ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް ދޮގުހެދި މީހުން ނައިސް ތިބެއްޖައޫއެވެ. އެއުރެންގެ ތެރެއިން ކާފިރުވި މީހުންނަށް، ވޭންދެނިވި އަޒާބު އައިސް ޖެހޭހުށްޓެވެ.","",""],["₉ سورة التوبة","91","لَّيۡسَ عَلَى ٱلضُّعَفَآءِ وَلَا عَلَى ٱلۡمَرۡضَىٰ وَلَا عَلَى ٱلَّذِينَ لَا يَجِدُونَ مَا يُنفِقُونَ حَرَجٌ إِذَا نَصَحُواْ لِلَّهِ وَرَسُولِهِۦۚ مَا عَلَى ٱلۡمُحۡسِنِينَ مِن سَبِيلٖۚ وَٱللَّهُ غَفُورٞ رَّحِيمٞ ٩١","ليس على الضعفاء ولا على المرضى ولا على الذين لا يجدون ما ينفقون حرج إذا نصحوا لله ورسوله ما على المحسنين من سبيل والله غفور رحيم","ނިކަމެތިންގެ މައްޗަކަށް، އަދި ބަލިމީހުންގެ މައްޗަކަށްވެސް، އަދި (ހަނގުރާމަޔަށްޓަކައި) ހޭދަކުރާނޭ އެއްޗެއް ނުލިބޭ މީހުންގެ މައްޗަކަށްވެސް ކުށްފާފައެއް ނެތެވެ. ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް އެއުރެން ތެދުވެރިވެ، އިހްލާސް ތެރި ވީނަމައެވެ. އިހްސާން ތެރިންގެ މައްޗަކަށް (އެއުރެން ކުށްވެރި ކުރާކަށް) އެއްވެސް މަގެއްނެތެވެ. ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","92","وَلَا عَلَى ٱلَّذِينَ إِذَا مَآ أَتَوۡكَ لِتَحۡمِلَهُمۡ قُلۡتَ لَآ أَجِدُ مَآ أَحۡمِلُكُمۡ عَلَيۡهِ تَوَلَّواْ وَّأَعۡيُنُهُمۡ تَفِيضُ مِنَ ٱلدَّمۡعِ حَزَنًا أَلَّا يَجِدُواْ مَا يُنفِقُونَ ٩٢","ولا على الذين إذا ما أتوك لتحملهم قلت لا أجد ما أحملكم عليه تولوا وأعينهم تفيض من الدمع حزنا ألا يجدوا ما ينفقون","އަދި ކަލޭގެފާނުގެ އަރިހުގައި ގެންދެވުމަށް (އެދި) ކަލޭގެފާނުގެ އަރިހަށް އައި މީހުންގެ މައްޗަކަށްވިޔަސް ކުށްފާފައެއް ނެތެވެ. ކަލޭގެފާނު (އެއުރެންނަށް) ވިދާޅުވީމުއެވެ. އޭގެމަތީގައި ތިޔަބައިމީހުން އުފުއްލަވާނޭ ސަވާރީއެއް ތިމަންކަލޭގެފާނަކަށް ލިބިވަޑައިގެންފައެއް ނުވެއެވެ. (އެހިނދު) އެއުރެން އެނބުރިދިޔައީ، އެއުރެންގެ ލޯތައް ކަރުނައިންފުރި، އޮހޭ ޙާލު ގައެވެ. އެއުރެން ހޭދަކުރާނޭ އެއްޗެއް އެއުރެންނަށް ނުލިބުނުކަމުގެ ހިތާމައިގައެވެ.","",""],["₉ سورة التوبة","93","۞إِنَّمَا ٱلسَّبِيلُ عَلَى ٱلَّذِينَ يَسۡتَـٔۡذِنُونَكَ وَهُمۡ أَغۡنِيَآءُۚ رَضُواْ بِأَن يَكُونُواْ مَعَ ٱلۡخَوَالِفِ وَطَبَعَ ٱللَّهُ عَلَىٰ قُلُوبِهِمۡ فَهُمۡ لَا يَعۡلَمُونَ ٩٣","إنما السبيل على الذين يستأذنونك وهم أغنياء رضوا بأن يكونوا مع الخوالف وطبع الله على قلوبهم فهم لا يعلمون","(ކުށްވެރިކުރުމުގެ) މަގު އޮތްކަން ކަށަވަރީ، މުއްސަނދިން ކަމުގައިވުމާއެކު (ހަނގުރާމަޔަށް ނުގޮސްތިބުމަށް) ކަލޭގެފާނުގެ އަރިހުން އިޒުނަށް އެދޭ މީހުންގެ މައްޗަށެވެ. (ހަނގުރާމަޔަށް) ނުގޮސްތިބޭ އަންހެނުންނާ އެކުގައި ވުމަށް އެއުރެން ރުހުނޫއެވެ. އަދި ﷲއެއުރެންގެ ހިތްތަކުގައި ސިއްކަގައްސަވައި ބަންދުކުރެއްވިއެވެ. ފަހެ، އެއުރެންނަކަށް ނޭނގެތެވެ.","",""],["₉ سورة التوبة","94","يَعۡتَذِرُونَ إِلَيۡكُمۡ إِذَا رَجَعۡتُمۡ إِلَيۡهِمۡۚ قُل لَّا تَعۡتَذِرُواْ لَن نُّؤۡمِنَ لَكُمۡ قَدۡ نَبَّأَنَا ٱللَّهُ مِنۡ أَخۡبَارِكُمۡۚ وَسَيَرَى ٱللَّهُ عَمَلَكُمۡ وَرَسُولُهُۥ ثُمَّ تُرَدُّونَ إِلَىٰ عَٰلِمِ ٱلۡغَيۡبِ وَٱلشَّهَٰدَةِ فَيُنَبِّئُكُم بِمَا كُنتُمۡ تَعۡمَلُونَ ٩٤","يعتذرون إليكم إذا رجعتم إليهم قل لا تعتذروا لن نؤمن لكم قد نبأنا الله من أخباركم وسيرى الله عملكم ورسوله ثم تردون إلى عالم الغيب والشهادة فينبئكم بما كنتم تعملون","ތިޔަބައިމީހުން އެއުރެންނާ ހަމަޔަށް އެނބުރި އަތުވެއްޖެހިނދު، އެއުރެން ތިޔަބައިމީހުންނަށް އުޒުރު ދައްކައި އުޅޭނެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން އުޒުރު ނުދައްކާށެވެ! ތިމަންމެން ތިޔަބައިމީހުންގެ ބަސް ތެދެއްނުކުރާނަމެވެ. ހަމަކަށަވަރުން، ﷲ، ތިޔަބައިމީހުންގެ ޚަބަރުތައް ތިމަންމެންނަށް އަންގަވައިފިއެވެ. އަދި ﷲ، ތިޔަބައިމީހުންގެ ޢަމަލުތައް ދެކެވޮޑިގެންވާނެތެވެ. އަދި އެކަލާނގެ ރަސޫލު އާވެސް ދެކެވަޑައިގަންނަވާނެތެވެ. ދެން ތިޔަބައިމީހުން، ރައްދުކުރައްވާހުށީ، ނުފެންނަ ކަންތަކާއި، ފެންނަ ކަންތައް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެ ހަޒުރަތަށެވެ. ފަހެ، އޭރުން ތިޔަބައިމީހުން ކޮށްއުޅުނު ކަންތަކުގެ ޚަބަރު، ތިޔަބައިމީހުންނަށް އެކަލާނގެ އަންގަވާނެތެވެ.","",""],["₉ سورة التوبة","95","سَيَحۡلِفُونَ بِٱللَّهِ لَكُمۡ إِذَا ٱنقَلَبۡتُمۡ إِلَيۡهِمۡ لِتُعۡرِضُواْ عَنۡهُمۡۖ فَأَعۡرِضُواْ عَنۡهُمۡۖ إِنَّهُمۡ رِجۡسٞۖ وَمَأۡوَىٰهُمۡ جَهَنَّمُ جَزَآءَۢ بِمَا كَانُواْ يَكۡسِبُونَ ٩٥","سيحلفون بالله لكم إذا انقلبتم إليهم لتعرضوا عنهم فأعرضوا عنهم إنهم رجس ومأواهم جهنم جزاء بما كانوا يكسبون","ތިޔަބައިމީހުން އެއުރެންގެ ގާތަށް އެނބުރި އަތުވެއްޖެނަމަ، އެއުރެންގެ ކިބައިން ތިޔަބައިމީހުން ދުރުހެލިވެގަތުމަށް، ﷲ ގަންދީ އެއުރެން ތިޔަބައިމީހުން ގާތުގައި ހުވާކޮށް ހަދާނެތެވެ. ފަހެ، ތިޔަބައިމީހުން އެއުރެންނާ ދުރުހެލިވާށެވެ! ހަމަކަށަވަރުން، އެއުރެންނަކީ ނަޖިސް ބަޔެކެވެ. އަދި އެއުރެން ތިބެނިވި ތަނަކީ ނަރަކައެވެ. (އެއީ) އެއުރެން ހޯދައިއުޅުނު ޢަމަލުތަކުގެ ޖަޒާއެއްގެ ގޮތުގައެވެ.","",""],["₉ سورة التوبة","96","يَحۡلِفُونَ لَكُمۡ لِتَرۡضَوۡاْ عَنۡهُمۡۖ فَإِن تَرۡضَوۡاْ عَنۡهُمۡ فَإِنَّ ٱللَّهَ لَا يَرۡضَىٰ عَنِ ٱلۡقَوۡمِ ٱلۡفَٰسِقِينَ ٩٦","يحلفون لكم لترضوا عنهم فإن ترضوا عنهم فإن الله لا يرضى عن القوم الفاسقين","އެއުރެންނަށް ތިޔަބައިމީހުން ރުހުމަށްޓަކައި، އެއުރެން ތިޔަބައިމީހުން ގާތުގައި ހުވާކޮށް އުޅޭނެތެވެ. ފަހެ، އެއުރެންނަށް ތިޔަބައިމީހުން ރުހުނަސް، ހަމަކަށަވަރުން، ފާސިގު ވެގެންވާ ބަޔަކަށް ﷲ ރުހިވޮޑިގެން ނުވާނެތެވެ.","",""],["₉ سورة التوبة","97","ٱلۡأَعۡرَابُ أَشَدُّ كُفۡرٗا وَنِفَاقٗا وَأَجۡدَرُ أَلَّا يَعۡلَمُواْ حُدُودَ مَآ أَنزَلَ ٱللَّهُ عَلَىٰ رَسُولِهِۦۗ وَٱللَّهُ عَلِيمٌ حَكِيمٞ ٩٧","الأعراب أشد كفرا ونفاقا وأجدر ألا يعلموا حدود ما أنزل الله على رسوله والله عليم حكيم","ކާފިރުކަމާއި، މުނާފިގުކަމުގައި އަޢުރާބީން މާހަރުކަށިކަން ބޮޑެވެ. އަދި ﷲ، އެކަލާނގެ ރަސޫލާއަށް ބާވައިލެއްވި ތަކެތީގެ އިންތައް ނޭނގުން އައުލާ ކަން ބޮޑެވެ. ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","98","وَمِنَ ٱلۡأَعۡرَابِ مَن يَتَّخِذُ مَا يُنفِقُ مَغۡرَمٗا وَيَتَرَبَّصُ بِكُمُ ٱلدَّوَآئِرَۚ عَلَيۡهِمۡ دَآئِرَةُ ٱلسَّوۡءِۗ وَٱللَّهُ سَمِيعٌ عَلِيمٞ ٩٨","ومن الأعراب من يتخذ ما ينفق مغرما ويتربص بكم الدوائر عليهم دائرة السوء والله سميع عليم","އަދި (ﷲގެ މަގުގައި) ހޭދަކުރާ އެއްޗެއް އެއީ، ގެއްލުމެއްކަމުގައި ބަލައި، ތިޔަބައިމީހުންނަށް ދެރަގޮތްތައް މެދުވެރިވުން އެދި ބަލަބަލާތިބޭ މީހުން، އަޢުރާބީންގެ ތެރެއިންވެތެވެ. ނުބައިގޮތް ދިމާވުންއޮތީ އެއުރެންގެ މައްޗަށެވެ. ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","99","وَمِنَ ٱلۡأَعۡرَابِ مَن يُؤۡمِنُ بِٱللَّهِ وَٱلۡيَوۡمِ ٱلۡأٓخِرِ وَيَتَّخِذُ مَا يُنفِقُ قُرُبَٰتٍ عِندَ ٱللَّهِ وَصَلَوَٰتِ ٱلرَّسُولِۚ أَلَآ إِنَّهَا قُرۡبَةٞ لَّهُمۡۚ سَيُدۡخِلُهُمُ ٱللَّهُ فِي رَحۡمَتِهِۦٓۚ إِنَّ ٱللَّهَ غَفُورٞ رَّحِيمٞ ٩٩","ومن الأعراب من يؤمن بالله واليوم الآخر ويتخذ ما ينفق قربات عند الله وصلوات الرسول ألا إنها قربة لهم سيدخلهم الله في رحمته إن الله غفور رحيم","ﷲއަށާއި، އާޚިރަތް ދުވަހަށް އީމާންވެ، އަދި (ﷲގެ މަގުގައި) ހޭދަކުރާ ތަކެއްޗަކީ، ﷲގެ ހަޒުރަތަށް ކުއްތަންވުމުގެ ސަބަބެއް ކަމުގައްޔާއި، ރަސޫލާގެ ހެޔޮދުއާތައް ލިބުމުގެ ސަބަބެއް ކަމުގައި ބަލާ މީހުންވެސް އަޢުރާބީންގެ ތެރެއިންވެތެވެ. ދަންނާށެވެ! ހަމަކަށަވަރުން، އެކަންތައްތައް އެއުރެންނަށް ވާހުށީ، ކުއްތަންވުމެއް ކަމުގައެވެ. ﷲ، އެކަލާނގެ ރަހުމަތްގެ ތެރެއަށް އެއުރެން ވައްދަވާނެތެވެ. ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","100","وَٱلسَّـٰبِقُونَ ٱلۡأَوَّلُونَ مِنَ ٱلۡمُهَٰجِرِينَ وَٱلۡأَنصَارِ وَٱلَّذِينَ ٱتَّبَعُوهُم بِإِحۡسَٰنٖ رَّضِيَ ٱللَّهُ عَنۡهُمۡ وَرَضُواْ عَنۡهُ وَأَعَدَّ لَهُمۡ جَنَّـٰتٖ تَجۡرِي تَحۡتَهَا ٱلۡأَنۡهَٰرُ خَٰلِدِينَ فِيهَآ أَبَدٗاۚ ذَٰلِكَ ٱلۡفَوۡزُ ٱلۡعَظِيمُ ١٠٠","والسابقون الأولون من المهاجرين والأنصار والذين اتبعوهم بإحسان رضي الله عنهم ورضوا عنه وأعد لهم جنات تجري تحتها الأنهار خالدين فيها أبدا ذلك الفوز العظيم","މުހާޖިރްނާއި، އަންޞާރުންގެ ތެރެއިން ކުރިން އިސްނެންގެވި ބޭކަލުންނާއި، ހެޔޮގޮތުގައި އެބޭކަލުންނާ ތަބާ ވީމީހުން (ދަންނާށެވެ!) ﷲ، އެއުރެންނަށް ރުހިވޮޑިގެންފިއެވެ. އަދި އެއުރެން އެކަލާނގެއަށް ރުހުނޫއެވެ. އަދި އެތަންތާނގެ ދަށުން ކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތައް، އެކަލާނގެ އެއުރެންނަށްޓަކައި ތައްޔާރުކުރެއްވިއެވެ. އެތާނގައި، އެއުރެން އަބަދަށް ދެމިތިބެނިވި ގޮތުގައެވެ. ބޮޑުވެގެންވާ ނަސީބު ލިބުމަކީ އެއީއެވެ.","",""],["₉ سورة التوبة","101","وَمِمَّنۡ حَوۡلَكُم مِّنَ ٱلۡأَعۡرَابِ مُنَٰفِقُونَۖ وَمِنۡ أَهۡلِ ٱلۡمَدِينَةِ مَرَدُواْ عَلَى ٱلنِّفَاقِ لَا تَعۡلَمُهُمۡۖ نَحۡنُ نَعۡلَمُهُمۡۚ سَنُعَذِّبُهُم مَّرَّتَيۡنِ ثُمَّ يُرَدُّونَ إِلَىٰ عَذَابٍ عَظِيمٖ ١٠١","وممن حولكم من الأعراب منافقون ومن أهل المدينة مردوا على النفاق لا تعلمهم نحن نعلمهم سنعذبهم مرتين ثم يردون إلى عذاب عظيم","އަދި ތިޔަބައިމީހުންގެ ވަށައިގެންވާ އަޢުރާބީންގެ ތެރެއިން މުނާފިގުންގެ ބަޔަކުވެސްވެއެވެ. އަދި މުނާފިގުކަމުގެ މައްޗަށް ހޭނިފައިތިބި ބަޔަކު އަލްމަދީނާގެ އަހުލުވެރިންގެ ތެރެއިންވެއެވެ. ކަލޭގެފާނަކަށް އެއުރެން އެނގިވަޑައެއް ނުގަނެތެވެ. ތިމަންރަސްކަލާނގެ އެއުރެން ދެނެވޮޑިގެންވަމެވެ. ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެފަހަރު އަޒާބު ދެއްވާހުށީމެވެ. ދެން ބޮޑުވެގެންވާ އަޒާބެއްގެ ތެރެއަށް އެއުރެން ރައްދުކުރައްވާ ހުށްޓެވެ.","",""],["₉ سورة التوبة","102","وَءَاخَرُونَ ٱعۡتَرَفُواْ بِذُنُوبِهِمۡ خَلَطُواْ عَمَلٗا صَٰلِحٗا وَءَاخَرَ سَيِّئًا عَسَى ٱللَّهُ أَن يَتُوبَ عَلَيۡهِمۡۚ إِنَّ ٱللَّهَ غَفُورٞ رَّحِيمٌ ١٠٢","وآخرون اعترفوا بذنوبهم خلطوا عملا صالحا وآخر سيئا عسى الله أن يتوب عليهم إن الله غفور رحيم","އަދި އެހެންބަޔަކު އެއުރެންގެ ކުށްތަކަށް އިޢުތިރާފް ވޫއެވެ. އެއުރެން ހެޔޮ ޢަމަލަކާއި، ނުބައި އެހެން ކަމަކާ އެއްކޮށްފައިވެއެވެ. ﷲ، އެއުރެން މައްޗަށް ތައުބާ ލެއްވުން ގާތްވެގެންވެތެވެ. ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","103","خُذۡ مِنۡ أَمۡوَٰلِهِمۡ صَدَقَةٗ تُطَهِّرُهُمۡ وَتُزَكِّيهِم بِهَا وَصَلِّ عَلَيۡهِمۡۖ إِنَّ صَلَوٰتَكَ سَكَنٞ لَّهُمۡۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ ١٠٣","خذ من أموالهم صدقة تطهرهم وتزكيهم بها وصل عليهم إن صلاتك سكن لهم والله سميع عليم","އޭގެސަބަބުން ކަލޭގެފާނު އެއުރެން ތާހިރުކުރައްވާނޭ، އަދި އެއުރެންނަށް ހެޔޮކަން އިތުރުކޮށްދެއްވާނޭ ސަދަގާތެއް، އެއުރެންގެ މުދަލުން ކަލޭގެފާނު ނަންގަވާށެވެ! އަދި އެއުރެންނަށްޓަކައި ކަލޭގެފާނު ދުއާކުރައްވާށެވެ! ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ދުއާއަކީ، އެއުރެންނަށްއޮތް ހިތްހަމަޖެހުމަކާއި، ރަހުމަތެކެވެ. ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","104","أَلَمۡ يَعۡلَمُوٓاْ أَنَّ ٱللَّهَ هُوَ يَقۡبَلُ ٱلتَّوۡبَةَ عَنۡ عِبَادِهِۦ وَيَأۡخُذُ ٱلصَّدَقَٰتِ وَأَنَّ ٱللَّهَ هُوَ ٱلتَّوَّابُ ٱلرَّحِيمُ ١٠٤","ألم يعلموا أن الله هو يقبل التوبة عن عباده ويأخذ الصدقات وأن الله هو التواب الرحيم","ހަމަކަށަވަރުން، ﷲއީ، އެކަލާނގެ އަޅުންގެ ކިބައިން ތައުބާ ގަބޫލުކުރައްވާ އަދި ސަދަގާތް ގަބޫލުކުރައްވާ ރަސްކަލާނގެކަމާއި، ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ތައުބާ ލައްވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން އެއުރެން ނުދަންނަނީ ހެއްޔެވެ؟","",""],["₉ سورة التوبة","105","وَقُلِ ٱعۡمَلُواْ فَسَيَرَى ٱللَّهُ عَمَلَكُمۡ وَرَسُولُهُۥ وَٱلۡمُؤۡمِنُونَۖ وَسَتُرَدُّونَ إِلَىٰ عَٰلِمِ ٱلۡغَيۡبِ وَٱلشَّهَٰدَةِ فَيُنَبِّئُكُم بِمَا كُنتُمۡ تَعۡمَلُونَ ١٠٥","وقل اعملوا فسيرى الله عملكم ورسوله والمؤمنون وستردون إلى عالم الغيب والشهادة فينبئكم بما كنتم تعملون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ޢަމަލުކުރާށެވެ! ފަހެ، ތިޔަބައިމީހުންގެ ޢަމަލުތައް ﷲ ދެކެވޮޑިގެންވާނެތެވެ. އަދި އެކަލާނގެ ރަސޫލު އާވެސް މެއެވެ. އަދި މުއުމިނު ތަކުންވެސް މެއެވެ. އަދި ނުފެންނަ ކަންތަކާއި، ފެންނަ ކަންތައް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެ ހަޒުރަތަށް ތިޔަބައިމީހުން ރައްދުކުރައްވާ ހުށްޓެވެ. ދެން ތިޔަބައިމީހުން ކޮށްއުޅުނު ޢަމަލުތަކުގެ ޚަބަރު ތިޔަބައިމީހުންނަށް އެކަލާނގެ އަންގަވާނެތެވެ.","",""],["₉ سورة التوبة","106","وَءَاخَرُونَ مُرۡجَوۡنَ لِأَمۡرِ ٱللَّهِ إِمَّا يُعَذِّبُهُمۡ وَإِمَّا يَتُوبُ عَلَيۡهِمۡۗ وَٱللَّهُ عَلِيمٌ حَكِيمٞ ١٠٦","وآخرون مرجون لأمر الله إما يعذبهم وإما يتوب عليهم والله عليم حكيم","އަދި އެހެންބަޔަކު ﷲގެ އަމުރުފުޅު އަތުވެއްޖައުމަށް ދާނދެން ފަސްކުރައްވާފައިވެއެވެ. އެހެންޏާ އެއުރެންނަށް އެކަލާނގެ އަޒާބު ދެއްވާނެތެވެ. އެހެންޏާ އެއުރެންގެ މައްޗަށް އެކަލާނގެ ތައުބާ ލައްވާނެތެވެ. ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","107","وَٱلَّذِينَ ٱتَّخَذُواْ مَسۡجِدٗا ضِرَارٗا وَكُفۡرٗا وَتَفۡرِيقَۢا بَيۡنَ ٱلۡمُؤۡمِنِينَ وَإِرۡصَادٗا لِّمَنۡ حَارَبَ ٱللَّهَ وَرَسُولَهُۥ مِن قَبۡلُۚ وَلَيَحۡلِفُنَّ إِنۡ أَرَدۡنَآ إِلَّا ٱلۡحُسۡنَىٰۖ وَٱللَّهُ يَشۡهَدُ إِنَّهُمۡ لَكَٰذِبُونَ ١٠٧","والذين اتخذوا مسجدا ضرارا وكفرا وتفريقا بين المؤمنين وإرصادا لمن حارب الله ورسوله من قبل وليحلفن إن أردنا إلا الحسنى والله يشهد إنهم لكاذبون","އަދި (މުއުމިނުންނަށް) ގެއްލުން ދިނުމަށާއި، ކާފިރުކަމަށާއި، މުއުމިނުންގެ ދެމެދުތައް ވަކިކުރުމަށާއި، ކުރިން ﷲއާއި ރަސޫލާއާ ހަނގުރާމަކުރި މީހުންނަށްޓަކައި، ބަލަބަލާ ތިބުމަށާއި (މިކަންކަމަށްޓަކައި) މިސްކިތެއް ހަދައިގެން އުޅުނު މީހުންވެސް އެއުރެންގެ ތެރެއިންވެއެވެ. ހެޔޮގޮތް މެނުވީ ތިމަންމެން ގަސްދެއް ނުކުރަމުއޭ ކިޔައި، އެއުރެން ހުވާކުރާނެކަން ކަށަވަރެވެ. ހަމަކަށަވަރުން، އެއުރެންނީ ދޮގުހަދާ ބަޔެއްކަމަށް، ﷲ ހެކިވެވޮޑިގެންވެތެވެ.","",""],["₉ سورة التوبة","108","لَا تَقُمۡ فِيهِ أَبَدٗاۚ لَّمَسۡجِدٌ أُسِّسَ عَلَى ٱلتَّقۡوَىٰ مِنۡ أَوَّلِ يَوۡمٍ أَحَقُّ أَن تَقُومَ فِيهِۚ فِيهِ رِجَالٞ يُحِبُّونَ أَن يَتَطَهَّرُواْۚ وَٱللَّهُ يُحِبُّ ٱلۡمُطَّهِّرِينَ ١٠٨","لا تقم فيه أبدا لمسجد أسس على التقوى من أول يوم أحق أن تقوم فيه فيه رجال يحبون أن يتطهروا والله يحب المطهرين","ދުވަހަކުވެސް ކަލޭގެފާނު އެ މިސްކިތުގައި (ނަމާދަށް) ގާއިމުވެ ނުހުންނަވާށެވެ! ހަމަކަށަވަރުން، ފުރަތަމަ ދުވަހުއްސުރެން ތަގުވާގެ މައްޗަށް ބިންގާ އެޅުއްވި މިސްކިތެއްގައި (އެބަހީ: ގުބާ މިސްކިތުގައި) ކަލޭގެފާނު ގާއިމުވެ ހުންނެވުން މާ ހައްގު ކަން ބޮޑެވެ. ތާހިރު ވެގަތުމަށް ލޯބިކުރާ މީހުންތަކެއް އެ މިސްކިތުގައި ވެއެވެ. ތާހިރު ވެގަންނަ މީހުންދެކެ ﷲ ލޯބިވެވޮޑިގެންވެތެވެ.","",""],["₉ سورة التوبة","109","أَفَمَنۡ أَسَّسَ بُنۡيَٰنَهُۥ عَلَىٰ تَقۡوَىٰ مِنَ ٱللَّهِ وَرِضۡوَٰنٍ خَيۡرٌ أَم مَّنۡ أَسَّسَ بُنۡيَٰنَهُۥ عَلَىٰ شَفَا جُرُفٍ هَارٖ فَٱنۡهَارَ بِهِۦ فِي نَارِ جَهَنَّمَۗ وَٱللَّهُ لَا يَهۡدِي ٱلۡقَوۡمَ ٱلظَّـٰلِمِينَ ١٠٩","أفمن أسس بنيانه على تقوى من الله ورضوان خير أم من أسس بنيانه على شفا جرف هار فانهار به في نار جهنم والله لا يهدي القوم الظالمين","ފަހެ، ހެޔޮކަންބޮޑީ، ﷲއަށް ތަގުވާވެރިވުމާއި، އެކަލާނގެ ރުހިވޮޑިގަތުން ލިބުމުގެ މައްޗަށް އެމީހެއްގެ ބިނާގެ ބިންގާ އެޅި މީހާ ހެއްޔެވެ؟ ނުވަތަ ވެއްޓިގެންދާ ގުންޑޮޅިއެއްގެ ތުންފަތްމަތީގައި (އެބަހީ: ނިފާގު ކަންމަތީގައި) އެމީހެއްގެ ބިނާގެ ބިންގާ އަޅައި، އެ ބިނާއާއެކު ނަރަކައިގެ އަލިފާންގަނޑަށް ވެއްޓުނު މީހާ ހެއްޔެވެ؟ އަނިޔާވެރި ބަޔަކަށް ﷲ ތެދުމަގެއް ނުދައްކަވާނެތެވެ.","",""],["₉ سورة التوبة","110","لَا يَزَالُ بُنۡيَٰنُهُمُ ٱلَّذِي بَنَوۡاْ رِيبَةٗ فِي قُلُوبِهِمۡ إِلَّآ أَن تَقَطَّعَ قُلُوبُهُمۡۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌ ١١٠","لا يزال بنيانهم الذي بنوا ريبة في قلوبهم إلا أن تقطع قلوبهم والله عليم حكيم","އެއުރެންގެ ހިތްތައް ބުރިބުރިވެގެން ދިއުމުން މެނުވީ، އެއުރެން ބިނާކުޅަ ބިނާ، އެއުރެންގެ ހިތްތަކުގައިވާ ޝައްކެއް ކަމުގައި ފިލައިނުދެތެވެ. ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","111","۞إِنَّ ٱللَّهَ ٱشۡتَرَىٰ مِنَ ٱلۡمُؤۡمِنِينَ أَنفُسَهُمۡ وَأَمۡوَٰلَهُم بِأَنَّ لَهُمُ ٱلۡجَنَّةَۚ يُقَٰتِلُونَ فِي سَبِيلِ ٱللَّهِ فَيَقۡتُلُونَ وَيُقۡتَلُونَۖ وَعۡدًا عَلَيۡهِ حَقّٗا فِي ٱلتَّوۡرَىٰةِ وَٱلۡإِنجِيلِ وَٱلۡقُرۡءَانِۚ وَمَنۡ أَوۡفَىٰ بِعَهۡدِهِۦ مِنَ ٱللَّهِۚ فَٱسۡتَبۡشِرُواْ بِبَيۡعِكُمُ ٱلَّذِي بَايَعۡتُم بِهِۦۚ وَذَٰلِكَ هُوَ ٱلۡفَوۡزُ ٱلۡعَظِيمُ ١١١","إن الله اشترى من المؤمنين أنفسهم وأموالهم بأن لهم الجنة يقاتلون في سبيل الله فيقتلون ويقتلون وعدا عليه حقا في التوراة والإنجيل والقرآن ومن أوفى بعهده من الله فاستبشروا ببيعكم الذي بايعتم به وذلك هو الفوز العظيم","ހަމަކަށަވަރުން، ﷲ، މުއުމިނުންގެ ކިބައިން އެއުރެންގެ ނަފްސު ތަކާއި، މުދާތައް، އެއުރެންނަށް ސުވަރުގެ ހުރިކަން އަންގަވައި، ބައްލަވައިގަތެވެ. އެއުރެން ﷲގެ މަގުގައި ހަނގުރާމަ ކުރެތެވެ. ފަހެ، އެއުރެން (ދުޝްމަނުން) ގަތުލު ކޮށް، އަދި އެއުރެން ގަތުލު ވެދެއެވެ. (އެއުރެންނަށް ސުވަރުގެ ހުރިކަމީ) ތައުރާތާއި، އިންޖީލާއި، ގުރްއާންގައި، އެކަލާނގެ ޛާތު ފުޅުގެ މައްޗަށް ހައްގު ގޮތުގައި ކުރައްވާފައިވާ ވައުދެކެވެ. އަދި އަހުދު ފުއްދުމުގައި، ﷲއަށްވުރެ ފުއްދުންތެރިކަން ބޮޑީ ކާކުހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުން ވިއްކި ވިއްކުމާމެދު އުފާކުރާހުށިކަމެވެ! ބޮޑުވެގެންވާ ނަސީބު ލިބުމަކީ ހަމަ އެއީއެވެ.","",""],["₉ سورة التوبة","112","ٱلتَّـٰٓئِبُونَ ٱلۡعَٰبِدُونَ ٱلۡحَٰمِدُونَ ٱلسَّـٰٓئِحُونَ ٱلرَّـٰكِعُونَ ٱلسَّـٰجِدُونَ ٱلۡأٓمِرُونَ بِٱلۡمَعۡرُوفِ وَٱلنَّاهُونَ عَنِ ٱلۡمُنكَرِ وَٱلۡحَٰفِظُونَ لِحُدُودِ ٱللَّهِۗ وَبَشِّرِ ٱلۡمُؤۡمِنِينَ ١١٢","التائبون العابدون الحامدون السائحون الراكعون الساجدون الآمرون بالمعروف والناهون عن المنكر والحافظون لحدود الله وبشر المؤمنين","(އެއީ) ތައުބާވާ މީހުންނެވެ. (ﷲއަށް) އަޅުކަންކުރާ މީހުންނެވެ. (އެކަލާނގެއަށް) ހަމްދުކުރާ މީހުންނެވެ. ރޯދަހިފާ މީހުންނެވެ. ރުކޫއު ކޮށް ސަޖިދަކުރާ މީހުންނެވެ. ހެޔޮކަންތަކަށް އަމުރު ކޮށް ނުބައިކަންތައް ނަހީކުރާ މީހުންނެވެ. އަދި ﷲ ކަނޑައަޅުއްވާފައިވާ އިންތަކަށް ރައްކާތެރިވާ މީހުންނެވެ. ކަލޭގެފާނު މުއުމިނުންނަށް އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާށެވެ!","",""],["₉ سورة التوبة","113","مَا كَانَ لِلنَّبِيِّ وَٱلَّذِينَ ءَامَنُوٓاْ أَن يَسۡتَغۡفِرُواْ لِلۡمُشۡرِكِينَ وَلَوۡ كَانُوٓاْ أُوْلِي قُرۡبَىٰ مِنۢ بَعۡدِ مَا تَبَيَّنَ لَهُمۡ أَنَّهُمۡ أَصۡحَٰبُ ٱلۡجَحِيمِ ١١٣","ما كان للنبي والذين آمنوا أن يستغفروا للمشركين ولو كانوا أولي قربى من بعد ما تبين لهم أنهم أصحاب الجحيم","ނަބިއްޔާއަކަށްވެސް، އަދި އީމާންވި މީހުންނަކަށްވެސް މުޝްރިކުންނަށްޓަކައި ފާފަފުއްސެވުންއެދި ދުއާކުރެއްވުމެއް ނެތެވެ. އެއުރެންނީ ގާތްތިމާގެ މީހުންކަމުގައި ވީނަމަވެހެވެ. ހަމަކަށަވަރުން، އެއުރެންނީ ނަރަކައިގެ އަހުލުވެރިންކަން އެއުރެންނަށް ފާޅުވެ އެނގުމަށްފަހުގައެވެ.","",""],["₉ سورة التوبة","114","وَمَا كَانَ ٱسۡتِغۡفَارُ إِبۡرَٰهِيمَ لِأَبِيهِ إِلَّا عَن مَّوۡعِدَةٖ وَعَدَهَآ إِيَّاهُ فَلَمَّا تَبَيَّنَ لَهُۥٓ أَنَّهُۥ عَدُوّٞ لِّلَّهِ تَبَرَّأَ مِنۡهُۚ إِنَّ إِبۡرَٰهِيمَ لَأَوَّـٰهٌ حَلِيمٞ ١١٤","وما كان استغفار إبراهيم لأبيه إلا عن موعدة وعدها إياه فلما تبين له أنه عدو لله تبرأ منه إن إبراهيم لأواه حليم","އެކަލޭގެފާނަށް (އެބަހީ: އިބްރާހީމްގެފާނަށް) އެކަލާނގެ ކުރައްވާފައިވާ ވައުދެއްގެ މަތިން މެނުވީ، އިބްރާހީމްގެފާނު، އެކަލޭގެފާނުގެ ބަފައިކަލުންނަށް އިސްތިޣްފާރުކުރެއްވުން ނުވެއެވެ. ފަހެ، އޭނާއަކީ ﷲގެ އަދާވަތް ތެރިޔެއްކަން އެކަލޭގެފާނަށް ބަޔާންވެ އެނގިވަޑައިގަތްހިނދު، އޭނާގެ ކިބައިން އެކަލޭގެފާނު ބަރީއަވެވަޑައިގަތެވެ. ހަމަކަށަވަރުން، އިބްރާހީމްގެފާނީ، ދުއާކުރެއްވުން ގިނަ، ކޯފާ މަޑު ބޭކަލެކެވެ.","",""],["₉ سورة التوبة","115","وَمَا كَانَ ٱللَّهُ لِيُضِلَّ قَوۡمَۢا بَعۡدَ إِذۡ هَدَىٰهُمۡ حَتَّىٰ يُبَيِّنَ لَهُم مَّا يَتَّقُونَۚ إِنَّ ٱللَّهَ بِكُلِّ شَيۡءٍ عَلِيمٌ ١١٥","وما كان الله ليضل قوما بعد إذ هداهم حتى يبين لهم ما يتقون إن الله بكل شيء عليم","ބަޔަކަށް ތެދުމަގު ދެއްކެވުމަށްފަހު، ﷲ، އެބަޔަކު މަގުފުރެއްދެވުމަށް އިރާދައެއް ނުކުރައްވަތެވެ. އެބަޔަކަށް އެކަމަކުން ދުރުވެ ރައްކާތެރިވާންވީ ކަމެއް ބަޔާންކޮށްދެއްވައިފުމަށް ދާނދެނެވެ. ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެ ކަމެއްމެ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","116","إِنَّ ٱللَّهَ لَهُۥ مُلۡكُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِۖ يُحۡيِۦ وَيُمِيتُۚ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِن وَلِيّٖ وَلَا نَصِيرٖ ١١٦","إن الله له ملك السماوات والأرض يحيي ويميت وما لكم من دون الله من ولي ولا نصير","ހަމަކަށަވަރުން، އުޑުތަކާއި ބިމުގެ ވެރިކަން މަލަކަ ވެގެންވަނީ ﷲއަށެވެ. ދިރުއްވަނީވެސް، އަދި މަރުގަންނަވަނީވެސް އެކަލާނގެއެވެ. އަދި ތިޔަބައިމީހުންނަކަށް ﷲ ފިޔަވައި އެއްވެސް އެހީތެރިޔަކު އަދި ނަސްރު ދޭނޭ މީހަކުވެސް ނުވެއެވެ.","",""],["₉ سورة التوبة","117","لَّقَد تَّابَ ٱللَّهُ عَلَى ٱلنَّبِيِّ وَٱلۡمُهَٰجِرِينَ وَٱلۡأَنصَارِ ٱلَّذِينَ ٱتَّبَعُوهُ فِي سَاعَةِ ٱلۡعُسۡرَةِ مِنۢ بَعۡدِ مَا كَادَ يَزِيغُ قُلُوبُ فَرِيقٖ مِّنۡهُمۡ ثُمَّ تَابَ عَلَيۡهِمۡۚ إِنَّهُۥ بِهِمۡ رَءُوفٞ رَّحِيمٞ ١١٧","لقد تاب الله على النبي والمهاجرين والأنصار الذين اتبعوه في ساعة العسرة من بعد ما كاد يزيغ قلوب فريق منهم ثم تاب عليهم إنه بهم رءوف رحيم","ހަމަކަށަވަރުން، ނަބިއްޔާގެ މައްޗަށާއި، މުހާޖިރްނާއި، އަންޞާރުންގެ މައްޗަށް ﷲ ތައުބާ ލެއްވިއެވެ. އެބޭކަލުންނީ، ދަތިކަމުގެ ވަގުތުގައި އެކަލޭގެފާނާ ތަބާވި ބޭކަލުންނެވެ. އޭގެތެރެއިން ބަޔެއްގެ ހިތްތައް، ތެދުމަގުން އެއްކިބާވެ ދިއުމަށް ގާތްވުމަށްފަހުގައެވެ. ދެން އެކަލާނގެ އެއުރެންގެ މައްޗަށް ތައުބާ ލެއްވިއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، އެއުރެންނަށް ނުހަނު އޯގާވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","118","وَعَلَى ٱلثَّلَٰثَةِ ٱلَّذِينَ خُلِّفُواْ حَتَّىٰٓ إِذَا ضَاقَتۡ عَلَيۡهِمُ ٱلۡأَرۡضُ بِمَا رَحُبَتۡ وَضَاقَتۡ عَلَيۡهِمۡ أَنفُسُهُمۡ وَظَنُّوٓاْ أَن لَّا مَلۡجَأَ مِنَ ٱللَّهِ إِلَّآ إِلَيۡهِ ثُمَّ تَابَ عَلَيۡهِمۡ لِيَتُوبُوٓاْۚ إِنَّ ٱللَّهَ هُوَ ٱلتَّوَّابُ ٱلرَّحِيمُ ١١٨","وعلى الثلاثة الذين خلفوا حتى إذا ضاقت عليهم الأرض بما رحبت وضاقت عليهم أنفسهم وظنوا أن لا ملجأ من الله إلا إليه ثم تاب عليهم ليتوبوا إن الله هو التواب الرحيم","އަދި ފަސްޖެހުނު ތިން މީހުންގެ މައްޗަށްވެސް (ތައުބާ ލެއްވި) މެއެވެ. ބިންގަނޑު ތަނަވަސްވެގެން ވުމާއެކުވެސް، އެއުރެންގެ މައްޗަށް އެ ބިން ދަތިވެ، އަދި އެއުރެންގެ އަމިއްލަ ނަފްސުތައް އެއުރެންގެ މައްޗަށް ދަތިވި ހިނދުގައެވެ. އަދި ﷲގެ ހަޒުރަތުން (އެބަހީ: އެކަލާނގެ ނުރުއްސެވުމުން) ސަލާމަތްވުމަށް، އެކަލާނގެ ހަޒުރަތަށް މެނުވީ ދާނޭ ތަނެއް ނެތްކަން އެއުރެންނަށް ޔަގީން ވީ ހިނދުގައެވެ. ދެން އެއުރެން ތައުބާ ވުމަށްޓަކައި އެކަލާނގެ އެއުރެންގެ މައްޗަށް ތައުބާ ލެއްވިއެވެ. ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ތައުބާ ގަބޫލުކުރައްވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₉ سورة التوبة","119","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ ٱتَّقُواْ ٱللَّهَ وَكُونُواْ مَعَ ٱلصَّـٰدِقِينَ ١١٩","يا أيها الذين آمنوا اتقوا الله وكونوا مع الصادقين","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރި ވާށެވެ! އަދި ތެދުވެރިންނާ އެކުގައި، ތިޔަބައިމީހުން ވާށެވެ!","",""],["₉ سورة التوبة","120","مَا كَانَ لِأَهۡلِ ٱلۡمَدِينَةِ وَمَنۡ حَوۡلَهُم مِّنَ ٱلۡأَعۡرَابِ أَن يَتَخَلَّفُواْ عَن رَّسُولِ ٱللَّهِ وَلَا يَرۡغَبُواْ بِأَنفُسِهِمۡ عَن نَّفۡسِهِۦۚ ذَٰلِكَ بِأَنَّهُمۡ لَا يُصِيبُهُمۡ ظَمَأٞ وَلَا نَصَبٞ وَلَا مَخۡمَصَةٞ فِي سَبِيلِ ٱللَّهِ وَلَا يَطَـُٔونَ مَوۡطِئٗا يَغِيظُ ٱلۡكُفَّارَ وَلَا يَنَالُونَ مِنۡ عَدُوّٖ نَّيۡلًا إِلَّا كُتِبَ لَهُم بِهِۦ عَمَلٞ صَٰلِحٌۚ إِنَّ ٱللَّهَ لَا يُضِيعُ أَجۡرَ ٱلۡمُحۡسِنِينَ ١٢٠","ما كان لأهل المدينة ومن حولهم من الأعراب أن يتخلفوا عن رسول الله ولا يرغبوا بأنفسهم عن نفسه ذلك بأنهم لا يصيبهم ظمأ ولا نصب ولا مخمصة في سبيل الله ولا يطئون موطئا يغيظ الكفار ولا ينالون من عدو نيلا إلا كتب لهم به عمل صالح إن الله لا يضيع أجر المحسنين","އަލްމަދީނާގެ އަހުލުވެރިންނާއި، އެއުރެންގެ ވަށައިގެންތިބޭ އަޢުރާބީންގެ މީހުންނަކަށް، ﷲގެ ރަސޫލާ އަރިހުގައި (ހަނގުރާމަޔަށް) ނުގޮސް ފަސްޖެހިފައި ތިބުމެއްނެތެވެ. އަދި އެކަލޭގެފާނުގެ ފުރާނަފުޅަށްވުރެ، އެއުރެންގެ ފުރާނަތަކަށް އިސްކަންދިނުމެއްނެތެވެ. އެހެނީ، އެއުރެންނަށް ސާލިހު ޢަމަލެއް ކަމުގައި ލިޔެވިގެން މެނުވީ، އެއުރެންނަށް އަނގަހިއްކުމެއް، އަދި ވަރުބަލިކަމެއްވެސް، އަދި ބަނޑުހައިހޫނުކަމެއްވެސް، ﷲގެ މަގުގައި އެއުރެންނަކަށް ނުޖެހޭނެއެވެ. އަދި ކާފިރުން ރުޅިއަރާނެ ތަނަކަށް، އެއުރެންނަކަށް ފިޔަވަޅެއް ނޭޅޭނެތެވެ. އަދި އަދާވަތް ތެރިއެއްގެ ކިބައިން ގެއްލުމެއް އެއުރެންނަކަށް ނުލިބޭނެތެވެ. ހަމަކަށަވަރުން، އިހްސާން ތެރިންގެ ދަރުމަ، ﷲގެއްލެނި ނުކުރައްވާނެތެވެ.","",""],["₉ سورة التوبة","121","وَلَا يُنفِقُونَ نَفَقَةٗ صَغِيرَةٗ وَلَا كَبِيرَةٗ وَلَا يَقۡطَعُونَ وَادِيًا إِلَّا كُتِبَ لَهُمۡ لِيَجۡزِيَهُمُ ٱللَّهُ أَحۡسَنَ مَا كَانُواْ يَعۡمَلُونَ ١٢١","ولا ينفقون نفقة صغيرة ولا كبيرة ولا يقطعون واديا إلا كتب لهم ليجزيهم الله أحسن ما كانوا يعملون","އަދި އެއުރެންނަށް ލިޔެވިގެންދާ ގޮތުގައި މެނުވީ، އެއުރެން ކުޑަ ހޭދައެއްވެސް، އަދި ބޮޑު ހޭދައެއްވެސް ނުކުރާނެތެވެ. އަދި ވާދީއެއްވެސް ކަޑައްތުކޮށް އެއުރެން ނުދާނެތެވެ. (އެއީ) އެއުރެން ޢަމަލު ކޮށް އުޅުނު އެންމެ ރީތިގޮތަށް، ﷲއެއުރެންނަށް، ޖަޒާ ދެއްވުމަށްޓަކައެވެ.","",""],["₉ سورة التوبة","122","۞وَمَا كَانَ ٱلۡمُؤۡمِنُونَ لِيَنفِرُواْ كَآفَّةٗۚ فَلَوۡلَا نَفَرَ مِن كُلِّ فِرۡقَةٖ مِّنۡهُمۡ طَآئِفَةٞ لِّيَتَفَقَّهُواْ فِي ٱلدِّينِ وَلِيُنذِرُواْ قَوۡمَهُمۡ إِذَا رَجَعُوٓاْ إِلَيۡهِمۡ لَعَلَّهُمۡ يَحۡذَرُونَ ١٢٢","وما كان المؤمنون لينفروا كافة فلولا نفر من كل فرقة منهم طائفة ليتفقهوا في الدين ولينذروا قومهم إذا رجعوا إليهم لعلهم يحذرون","އަދި އެންމެން އެކުގައި ހަނގުރާމަޔަށް ނުކުތުމެއް، މުއުމިނުންނަކަށް ނެތެވެ. ފަހެ، އެއުރެންގެ ތެރެއިން ކޮންމެ ގަބީލާއަކުން ބަޔަކު ހަނގުރާމަޔަށް ނުކުތްނަމަ ކިހާރަނގަޅުހޭ؟ (އެއީ) އެއުރެން (އެބަހީ: ނުގޮސްތިބި މީހުން) ދީން އުނގެނި ދަސްކުރުމަށެވެ. އަދި އެއުރެންގެ ގައުމުގެމީހުން (އެބަހީ: ހަނގުރާމަޔަށް ނުކުތް މީހުން) އެއުރެންގެ ގާތަށް އެނބުރި އަތުވެއްޖެހިނދު، އެއުރެންނަށް އިންޒާރުކުރުމަށްޓަކައެވެ. (އެއީ) އެއުރެން ބިރުވެތިވެ، ރައްކާތެރިވުމަށްޓަކައެވެ.","",""],["₉ سورة التوبة","123","يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ قَٰتِلُواْ ٱلَّذِينَ يَلُونَكُم مِّنَ ٱلۡكُفَّارِ وَلۡيَجِدُواْ فِيكُمۡ غِلۡظَةٗۚ وَٱعۡلَمُوٓاْ أَنَّ ٱللَّهَ مَعَ ٱلۡمُتَّقِينَ ١٢٣","يا أيها الذين آمنوا قاتلوا الذين يلونكم من الكفار وليجدوا فيكم غلظة واعلموا أن الله مع المتقين","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ކާފިރުންގެ ތެރެއިން ތިޔަބައިމީހުންނާ ގާތުގައިތިބި މީހުންނާ ތިޔަބައިމީހުން ހަނގުރާމަ ކުރާށެވެ! އަދި ތިޔަބައިމީހުންގެ ކިބައިން ހަރުކަށިކަން އެއުރެން ދެކޭހުށިކަމެވެ! އަދި ހަމަކަށަވަރުން، ﷲ ވޮޑިގެންވަނީ، ތަގުވާވެރިންނާ އެކުގައިކަން ތިޔަބައިމީހުން ދަންނާށެވެ!","",""],["₉ سورة التوبة","124","وَإِذَا مَآ أُنزِلَتۡ سُورَةٞ فَمِنۡهُم مَّن يَقُولُ أَيُّكُمۡ زَادَتۡهُ هَٰذِهِۦٓ إِيمَٰنٗاۚ فَأَمَّا ٱلَّذِينَ ءَامَنُواْ فَزَادَتۡهُمۡ إِيمَٰنٗا وَهُمۡ يَسۡتَبۡشِرُونَ ١٢٤","وإذا ما أنزلت سورة فمنهم من يقول أيكم زادته هذه إيمانا فأما الذين آمنوا فزادتهم إيمانا وهم يستبشرون","ސޫރަތެއް ބާވައިލައްވައިފިނަމަ، އެ ސޫރަތުން އެމީހެއްގެ އީމާން ކަން އިތުރުވީ ތިޔަބައިމީހުންގެ ތެރެއިން ކާކުހޭ ބުނެއުޅޭ މީހުން އެއުރެންގެ ތެރެއިންވެއެވެ. ފަހެ، އީމާން ވެއްޖެ މީސްތަކުން ދަންނާށެވެ! ފަހެ، އެއުރެން (އެކަމަށްޓަކައި) އުފާކުރާ ޙާލު، އެއުރެންގެ އީމާން ކަން އިތުރުވިއެވެ.","",""],["₉ سورة التوبة","125","وَأَمَّا ٱلَّذِينَ فِي قُلُوبِهِم مَّرَضٞ فَزَادَتۡهُمۡ رِجۡسًا إِلَىٰ رِجۡسِهِمۡ وَمَاتُواْ وَهُمۡ كَٰفِرُونَ ١٢٥","وأما الذين في قلوبهم مرض فزادتهم رجسا إلى رجسهم وماتوا وهم كافرون","އަދި އެއުރެންގެ ހިތްތަކުގައި ބަލިމަޑުކަމެއްވާ މީހުން ދަންނާށެވެ! ފަހެ، އެއުރެންގެ ކާފިރުކަމުގެ ތެރެއަށް ކާފިރު ކަން އެއުރެންނަށް އިތުރުވިއެވެ. އަދި ކާފިރުން ކަމުގައިވާ ޙާލު، އެއުރެން މަރުވިއެވެ.","",""],["₉ سورة التوبة","126","أَوَلَا يَرَوۡنَ أَنَّهُمۡ يُفۡتَنُونَ فِي كُلِّ عَامٖ مَّرَّةً أَوۡ مَرَّتَيۡنِ ثُمَّ لَا يَتُوبُونَ وَلَا هُمۡ يَذَّكَّرُونَ ١٢٦","أولا يرون أنهم يفتنون في كل عام مرة أو مرتين ثم لا يتوبون ولا هم يذكرون","އަދި ކޮންމެ އަހަރަކު އެއްފަހަރު، ނުވަތަ ދެފަހަރު (ދަތިތަކާއި ބަލިމަޑުކަން ކުރިމަތި ކުރައްވައި) އެއުރެން އިމްތިހާނުކުރައްވާތީ، އެއުރެން ނުދެކޭހެއްޔެވެ؟ ދެންވެސް އެއުރެން ތައުބާއެއް ނުވެތެވެ. އަދި އެއުރެން ހަނދާންކޮށް ވައުޒެއް ލިބިއެއް ނުގަނެއެވެ.","",""],["₉ سورة التوبة","127","وَإِذَا مَآ أُنزِلَتۡ سُورَةٞ نَّظَرَ بَعۡضُهُمۡ إِلَىٰ بَعۡضٍ هَلۡ يَرَىٰكُم مِّنۡ أَحَدٖ ثُمَّ ٱنصَرَفُواْۚ صَرَفَ ٱللَّهُ قُلُوبَهُم بِأَنَّهُمۡ قَوۡمٞ لَّا يَفۡقَهُونَ ١٢٧","وإذا ما أنزلت سورة نظر بعضهم إلى بعض هل يراكم من أحد ثم انصرفوا صرف الله قلوبهم بأنهم قوم لا يفقهون","އަދި ސޫރަތެއް ބާވައިލައްވައިފިނަމަ، އެއުރެންގެ އެކަކު އަނެކަކަށް ބަލައިލައެވެ. (އަދި ބުނެއެވެ.) އެކަކުވެސް ތިޔަބައިމީހުން ދެކޭހެއްޔެވެ؟ ދެން އެއުރެން އެނބުރި ހިނގައިދެއެވެ. ﷲއެއުރެންގެ ހިތްތައް (ތެދުމަގުން އެއްކިބާ ކުރައްވައި) އަނބުރުއްވައިލެއްވިއެވެ. (އެއީ) އެއުރެންނީ، ނުވިސްނޭ ބަޔަކު ކަމުގައިވާ ކަމަށްޓަކައެވެ.","",""],["₉ سورة التوبة","128","لَقَدۡ جَآءَكُمۡ رَسُولٞ مِّنۡ أَنفُسِكُمۡ عَزِيزٌ عَلَيۡهِ مَا عَنِتُّمۡ حَرِيصٌ عَلَيۡكُم بِٱلۡمُؤۡمِنِينَ رَءُوفٞ رَّحِيمٞ ١٢٨","لقد جاءكم رسول من أنفسكم عزيز عليه ما عنتم حريص عليكم بالمؤمنين رءوف رحيم","ހަމަތިޔަބައިމީހުންގެ ތެރެއިންވާ ރަސޫލަކު ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ގާތަށް ވަޑައިގެންފިއެވެ. ތިޔަބައިމީހުންނަށް އުނދަގޫވެ ދަތިވެއްޖެ ކޮންމެ ކަމެއް، އެކަލޭގެފާނަށް ބޮޑުކަމަކަށް ވެއެވެ. އެކަލޭގެފާނީ (ތިޔަބައިމީހުންނަށް ތެދުމަގު ލިބުމުގެ މައްޗަށް) ދަހިވެތިވެވަޑައިގެންވާ ބޭކަލެކެވެ. މުއުމިނުންނަށް ނުހަނު އޯގާވެރި، ރަޙިމު ހުރި ބޭކަލެކެވެ.","",""],["₉ سورة التوبة","129","فَإِن تَوَلَّوۡاْ فَقُلۡ حَسۡبِيَ ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَۖ عَلَيۡهِ تَوَكَّلۡتُۖ وَهُوَ رَبُّ ٱلۡعَرۡشِ ٱلۡعَظِيمِ ١٢٩","فإن تولوا فقل حسبي الله لا إله إلا هو عليه توكلت وهو رب العرش العظيم","ފަހެ، އެއުރެން އެނބުރި ފުރަގަސްދީފިނަމަ، ފަހެ، ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނަށް ﷲ ފުދެއެވެ. އެކަލާނގެ މެނުވީ (ހައްގު ވެގެން އަޅުކަމެއް ވެވޭ) އިލާހަކު ނުވެއެވެ. ހަމައެކަނި އެކަލާނގެއަށް ތިމަންކަލޭގެފާނު ވަކީލުކުރައްވައިފީމެވެ. އެކަލާނގެއީ، ބޮޑުވެގެންވާ ޢަރްޝުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["₁₀ سورة يونس","1","بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ\n<br><br>\nالٓرۚ تِلۡكَ ءَايَٰتُ ٱلۡكِتَٰبِ ٱلۡحَكِيمِ ١","بسم الله الرحمن الرحيم الر تلك آيات الكتاب الحكيم","ا ل ر (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.) މިއީ ހިކުމަތް ތެރި ފޮތުގެ (އެބަހީ: ގުރްއާންގެ) އާޔަތް ތަކެވެ.","",""],["₁₀ سورة يونس","2","أَكَانَ لِلنَّاسِ عَجَبًا أَنۡ أَوۡحَيۡنَآ إِلَىٰ رَجُلٖ مِّنۡهُمۡ أَنۡ أَنذِرِ ٱلنَّاسَ وَبَشِّرِ ٱلَّذِينَ ءَامَنُوٓاْ أَنَّ لَهُمۡ قَدَمَ صِدۡقٍ عِندَ رَبِّهِمۡۗ قَالَ ٱلۡكَٰفِرُونَ إِنَّ هَٰذَا لَسَٰحِرٞ مُّبِينٌ ٢","أكان للناس عجبا أن أوحينا إلى رجل منهم أن أنذر الناس وبشر الذين آمنوا أن لهم قدم صدق عند ربهم قال الكافرون إن هذا لساحر مبين","މީސްތަކުންނަށް އިންޒާރުކުރެއްވުމަށާއި، އީމާން ވެއްޖެ މީސްތަކުންނަށް އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި އިސްކަމާއި، މަތިވެރި މަގާމް ހުރިކަމުގެ އުފާވެރި ޚަބަރު ދެއްވުމަށް، ތިމަންރަސްކަލާނގެ އެއުރެންގެ ތެރެއިން ފިރިހެނަކަށް، ވަހީ އިއްވެވިކަން މީސްތަކުންނަށް އަޖާއިބަކަށްވީހެއްޔެވެ؟ ކާފިރުވި މީހުން ބުނެފޫއެވެ. ހަމަކަށަވަރުން، މިއީ (އެބަހީ: މުޙައްމަދުގެފާނީ) ފާޅުވެ ބަޔާން ވެގެންވާ ޖާދޫގަރެކެވެ.","",""],["₁₀ سورة يونس","3","إِنَّ رَبَّكُمُ ٱللَّهُ ٱلَّذِي خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضَ فِي سِتَّةِ أَيَّامٖ ثُمَّ ٱسۡتَوَىٰ عَلَى ٱلۡعَرۡشِۖ يُدَبِّرُ ٱلۡأَمۡرَۖ مَا مِن شَفِيعٍ إِلَّا مِنۢ بَعۡدِ إِذۡنِهِۦۚ ذَٰلِكُمُ ٱللَّهُ رَبُّكُمۡ فَٱعۡبُدُوهُۚ أَفَلَا تَذَكَّرُونَ ٣","إن ربكم الله الذي خلق السماوات والأرض في ستة أيام ثم استوى على العرش يدبر الأمر ما من شفيع إلا من بعد إذنه ذلكم الله ربكم فاعبدوه أفلا تذكرون","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއީ، ﷲއެވެ. އެކަލާނގެއީ، އުޑުތަކާއި ބިން ހަ ދުވަހުގެ ތެރޭގައި ހެއްދެވި ރަސްކަލާނގެއެވެ. ދެން ޢަރްޝުގެ މައްޗަށް އެކަލާނގެ އިސްތިވާ ވެވޮޑިގެންވިއެވެ. އެކަލާނގެ (އެންމެހާ) ކަންތައްތައް މިންވަރު ކުރައްވައި ތަދްބީރުކުރައްވަތެވެ. އެކަލާނގެ އިޒުނަ ފުޅަށް ފަހުގައި މެނުވީ (އެއްވެސް މީހަކަށް ޝަފާއަތް ތެރިވާނޭ) ޝަފާއަތް ތެރިޔަކު ނުވެއެވެ. އެއީ ތިޔަބައިމީހުންގެ ވެރި ﷲއެވެ. ފަހެ، ތިޔަބައިމީހުން އެކަލާނގެއަށް އަޅުކަން ކުރާށެވެ! ފަހެ، ތިޔަބައިމީހުން ހަނދުމަ ނުކުރަނީހެއްޔެވެ؟","",""],["₁₀ سورة يونس","4","إِلَيۡهِ مَرۡجِعُكُمۡ جَمِيعٗاۖ وَعۡدَ ٱللَّهِ حَقًّاۚ إِنَّهُۥ يَبۡدَؤُاْ ٱلۡخَلۡقَ ثُمَّ يُعِيدُهُۥ لِيَجۡزِيَ ٱلَّذِينَ ءَامَنُواْ وَعَمِلُواْ ٱلصَّـٰلِحَٰتِ بِٱلۡقِسۡطِۚ وَٱلَّذِينَ كَفَرُواْ لَهُمۡ شَرَابٞ مِّنۡ حَمِيمٖ وَعَذَابٌ أَلِيمُۢ بِمَا كَانُواْ يَكۡفُرُونَ ٤","إليه مرجعكم جميعا وعد الله حقا إنه يبدأ الخلق ثم يعيده ليجزي الذين آمنوا وعملوا الصالحات بالقسط والذين كفروا لهم شراب من حميم وعذاب أليم بما كانوا يكفرون","ތިޔަބައިމީހުން އެންމެން ރުޖޫއަ ވުން ވަނީ، އެކަލާނގެ ހަޒުރަތަށެވެ. (މިއީ) ﷲގެ ހައްގު ވައުދު ފުޅެވެ. ހަމަކަށަވަރުން، ނެތުމުގެ ތެރެއިން ޚަލްގު ތަކުން އަލަށް އުފައްދަވައި، ދެން އަލުން އެ ޚަލްގު ތަކުން އިއާދަކުރައްވަނީ، އެކަލާނގެއެވެ. (އެއީ) އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަމީހުންނަށް ޢަދުލުވެރި ގޮތުން ޖަޒާ ދެއްވުމަށްޓަކައެވެ. އަދި ކާފިރުވި މީހުންނަށް އެއުރެން ކާފިރުވެ އުޅުނުކަމުގެ ސަބަބުން، ކެކިކެކި ހުންނަ ހޫނުފެނުގެ ބުއިމަކާއި، ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["₁₀ سورة يونس","5","هُوَ ٱلَّذِي جَعَلَ ٱلشَّمۡسَ ضِيَآءٗ وَٱلۡقَمَرَ نُورٗا وَقَدَّرَهُۥ مَنَازِلَ لِتَعۡلَمُواْ عَدَدَ ٱلسِّنِينَ وَٱلۡحِسَابَۚ مَا خَلَقَ ٱللَّهُ ذَٰلِكَ إِلَّا بِٱلۡحَقِّۚ يُفَصِّلُ ٱلۡأٓيَٰتِ لِقَوۡمٖ يَعۡلَمُونَ ٥","هو الذي جعل الشمس ضياء والقمر نورا وقدره منازل لتعلموا عدد السنين والحساب ما خلق الله ذلك إلا بالحق يفصل الآيات لقوم يعلمون","އެކަލާނގެއީ، އަލިކަމެއްކަމުގައި އިރު ލައްވައި، ނޫރެއްކަމުގައި ހަނދު ލެއްވި ރަސްކަލާނގެއެވެ. އަދި އެ ހަނދު ހިނގުމަށް މަންޒިލް ތަކެއް މިންވަރުކުރެއްވިއެވެ. (އެއީ) ތިޔަބައިމީހުން އަހަރުތަކުގެ އަދަދާއި (މައްސަރުތަކާއި ދުވަސްތަކުގެ) ހިސާބު ދެނެގަތުމަށްޓަކައެވެ. ހައްގު ގޮތުން މެނުވީ، ﷲ، އެތަކެތި ނަހައްދަވައެވެ. އެނގޭބަޔަކަށް އެކަލާނގެ އާޔަތްތައް ތަފްޞީލު ކޮށްދެއްވަތެވެ.","",""],["₁₀ سورة يونس","6","إِنَّ فِي ٱخۡتِلَٰفِ ٱلَّيۡلِ وَٱلنَّهَارِ وَمَا خَلَقَ ٱللَّهُ فِي ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ لَأٓيَٰتٖ لِّقَوۡمٖ يَتَّقُونَ ٦","إن في اختلاف الليل والنهار وما خلق الله في السماوات والأرض لآيات لقوم يتقون","ހަމަކަށަވަރުން، ރޭދުވާ ތަފާތުވުމުގައްޔާއި އުޑުތަކާއި، ބިމުގައި ﷲ ހެއްދެވި (އެންމެހައި) ތަކެތީގައި، ތަގުވާވެރިވާ ބަޔަކަށް ދަލީލު ތަކެއްވާކަން ކަށަވަރެވެ.","",""],["₁₀ سورة يونس","7","إِنَّ ٱلَّذِينَ لَا يَرۡجُونَ لِقَآءَنَا وَرَضُواْ بِٱلۡحَيَوٰةِ ٱلدُّنۡيَا وَٱطۡمَأَنُّواْ بِهَا وَٱلَّذِينَ هُمۡ عَنۡ ءَايَٰتِنَا غَٰفِلُونَ ٧","إن الذين لا يرجون لقاءنا ورضوا بالحياة الدنيا واطمأنوا بها والذين هم عن آياتنا غافلون","ހަމަށަވަރުން، ތިމަންރަސްކަލާނގެއާ ބައްދަލުވާން ނޭދޭ، އަދި ދުނިޔޭގެ ދިރިއުޅުމަށްރުހި، އަދި އެކަމަށް ހިތްހަމަޖައްސައިގެންތިބެ ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާމެދު ޣާފިލުވި މީހުން (ދަންނާށެވެ!) އެއުރެން ތިބެނިވި ތަނަކީ، ނަރަކައެވެ. (އެއީ) އެއުރެން ހޯދައިއުޅުނު ޢަމަލުތަކުގެ ސަބަބުންނެވެ.","",""],["₁₀ سورة يونس","8","أُوْلَـٰٓئِكَ مَأۡوَىٰهُمُ ٱلنَّارُ بِمَا كَانُواْ يَكۡسِبُونَ ٨","أولئك مأواهم النار بما كانوا يكسبون","ހަމަށަވަރުން، ތިމަންރަސްކަލާނގެއާ ބައްދަލުވާން ނޭދޭ، އަދި ދުނިޔޭގެ ދިރިއުޅުމަށްރުހި، އަދި އެކަމަށް ހިތްހަމަޖައްސައިގެންތިބެ ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާމެދު ޣާފިލުވި މީހުން (ދަންނާށެވެ!) އެއުރެން ތިބެނިވި ތަނަކީ، ނަރަކައެވެ. (އެއީ) އެއުރެން ހޯދައިއުޅުނު ޢަމަލުތަކުގެ ސަބަބުންނެވެ.","",""],["₁₀ سورة يونس","9","إِنَّ ٱلَّذِينَ ءَامَنُواْ وَعَمِلُواْ ٱلصَّـٰلِحَٰتِ يَهۡدِيهِمۡ رَبُّهُم بِإِيمَٰنِهِمۡۖ تَجۡرِي مِن تَحۡتِهِمُ ٱلۡأَنۡهَٰرُ فِي جَنَّـٰتِ ٱلنَّعِيمِ ٩","إن الذين آمنوا وعملوا الصالحات يهديهم ربهم بإيمانهم تجري من تحتهم الأنهار في جنات النعيم","ހަމަކަށަވަރުން، އީމާންވެ، ސާލިހު ޢަމަލުތައް ކުޅަމީހުންނަށް، އެއުރެންގެ އީމާންކަމުގެ ސަބަބުން، އެއުރެންގެ ވެރިރަސްކަލާނގެ އެއުރެންނަށް ތެދުމަގު ދައްކަވާނެތެވެ. ނިއުމަތްގެ ސުވަރުގެތަކުގައި، އެއުރެންގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުންނާނެތެވެ.","",""],["₁₀ سورة يونس","10","دَعۡوَىٰهُمۡ فِيهَا سُبۡحَٰنَكَ ٱللَّهُمَّ وَتَحِيَّتُهُمۡ فِيهَا سَلَٰمٞۚ وَءَاخِرُ دَعۡوَىٰهُمۡ أَنِ ٱلۡحَمۡدُ لِلَّهِ رَبِّ ٱلۡعَٰلَمِينَ ١٠","دعواهم فيها سبحانك اللهم وتحيتهم فيها سلام وآخر دعواهم أن الحمد لله رب العالمين","އެތާނގައި، އެއުރެންގެ ދުއާއަކީ [سبحانك اللّهم] އެވެ. އޭ ހައްދަވާ ބޮޑުކުރެއްވި ރަސްކަލާކޯއެވެ! އިބަރަސްކަލާނގެއަށް އަޅަމެން ތަސްބީހަ ދަންނަވަމެވެ. އަދި އެތާނގައި، އެއުރެންގެ ތަޙިއްޔަތަކީ، [ސަލާމް] އެވެ. އަދި އެއުރެންގެ ދުއާގެ ނިންމުމަކީ، [الحمد للَّه رب العالمين] އެވެ. ހަމްދު ހުރީ އާލަމްތަކުގެ ވެރި ﷲއަށެވެ.","",""],["₁₀ سورة يونس","11","۞وَلَوۡ يُعَجِّلُ ٱللَّهُ لِلنَّاسِ ٱلشَّرَّ ٱسۡتِعۡجَالَهُم بِٱلۡخَيۡرِ لَقُضِيَ إِلَيۡهِمۡ أَجَلُهُمۡۖ فَنَذَرُ ٱلَّذِينَ لَا يَرۡجُونَ لِقَآءَنَا فِي طُغۡيَٰنِهِمۡ يَعۡمَهُونَ ١١","ولو يعجل الله للناس الشر استعجالهم بالخير لقضي إليهم أجلهم فنذر الذين لا يرجون لقاءنا في طغيانهم يعمهون","ހެޔޮކަމާއި، ސަވާބު އަވަސްކޮށްދެއްވުމަށް މީސްތަކުން އެދޭހިނދު، އެކަން އަވަސްކޮށްދެއްވާ ފަދައިން، ﷲއެއުރެންނަށް ނުބަޔާއި، ޢިގާބު އަވަސްކޮށްދެއްވާނަމަ، އެއުރެންގެ އަޖަލު ޖެހި، އެހިނދު އެހިނދަށް ނިމިއްޖައީހެވެ. ފަހެ، (ގިޔާމަތް ދުވަހުން) ތިމަންރަސްކަލާނގެއާ ބައްދަލުވާން ނޭދޭމީހުން އެއުރެންގެ ފުރެދުމުގައި، ދެފުށު އެޅިއެޅިތިބޭ ޙާލު، އެއުރެން ދޫކޮށްލައްވައި، ބައިތިއްބަވާހުށީމެވެ.","",""],["₁₀ سورة يونس","12","وَإِذَا مَسَّ ٱلۡإِنسَٰنَ ٱلضُّرُّ دَعَانَا لِجَنۢبِهِۦٓ أَوۡ قَاعِدًا أَوۡ قَآئِمٗا فَلَمَّا كَشَفۡنَا عَنۡهُ ضُرَّهُۥ مَرَّ كَأَن لَّمۡ يَدۡعُنَآ إِلَىٰ ضُرّٖ مَّسَّهُۥۚ كَذَٰلِكَ زُيِّنَ لِلۡمُسۡرِفِينَ مَا كَانُواْ يَعۡمَلُونَ ١٢","وإذا مس الإنسان الضر دعانا لجنبه أو قاعدا أو قائما فلما كشفنا عنه ضره مر كأن لم يدعنا إلى ضر مسه كذلك زين للمسرفين ما كانوا يعملون","އަދި އިންސާނާއަށް އުނދަގުލެއް ޖެހިއްޖެނަމަ، އޮށޯވެ އޮވެގެން ނުވަތަ އިށީނދެ އިނދެގެން، ނުވަތަ ކޮޅަށް ހުރެގެން، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ދުއާކުރެތެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ އެމީހެއްގެ ކިބައިން އެ އުނދަގޫ ފިއްލަވައިފުމުން، އޭނާ (އެދާ މަގުން) ހިނގައިދެއެވެ. އުނދަގުލެއްޖެހިގެން ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ދުއާ ވެސް ނުކުރާކަހަލައެވެ. ކާފިރުންނަށް އެއުރެން ކޮށްއުޅުނު ޢަމަލުތައް ޒީނަތްތެރި ކުރައްވާފައިވަނީ އެފަދައިންނެވެ.","",""],["₁₀ سورة يونس","13","وَلَقَدۡ أَهۡلَكۡنَا ٱلۡقُرُونَ مِن قَبۡلِكُمۡ لَمَّا ظَلَمُواْ وَجَآءَتۡهُمۡ رُسُلُهُم بِٱلۡبَيِّنَٰتِ وَمَا كَانُواْ لِيُؤۡمِنُواْۚ كَذَٰلِكَ نَجۡزِي ٱلۡقَوۡمَ ٱلۡمُجۡرِمِينَ ١٣","ولقد أهلكنا القرون من قبلكم لما ظلموا وجاءتهم رسلهم بالبينات وما كانوا ليؤمنوا كذلك نجزي القوم المجرمين","އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ކުރީގެ އުއްމަތްތަކުގެ މީހުންގެ ގާތަށް މުއުޖުޒާތް ތަކާއިގެން ރަސޫލުން ވަޑައިގަތުމުން، އެއުރެން އަނިޔާވެރިވީހިނދު، އެ އުއްމަތްތައް ހަލާކު ކުރައްވައި ނެތިކުރެއްވީމެވެ. އެއުރެންނީ އީމާން ވާނޭ ބަޔަކު ކަމުގައި ނުވެތެވެ. ކުށްވެރިވި މީހުންނަށް، ތިމަންރަސްކަލާނގެ ޖަޒާ ދެއްވަނީ އެފަދައިންނެވެ.","",""],["₁₀ سورة يونس","14","ثُمَّ جَعَلۡنَٰكُمۡ خَلَـٰٓئِفَ فِي ٱلۡأَرۡضِ مِنۢ بَعۡدِهِمۡ لِنَنظُرَ كَيۡفَ تَعۡمَلُونَ ١٤","ثم جعلناكم خلائف في الأرض من بعدهم لننظر كيف تعملون","ދެން އެއުރެންގެ ފަހުން ބިމުގައި ޚަލީފާ އިން ކަމުގައި ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން ލެއްވީމެވެ. އެއީ ތިޔަބައިމީހުން ކަންތައްކުރަނީ ކޮންފަދައަކުންތޯ ބެއްލެވުމަށްޓަކައެވެ.","",""],["₁₀ سورة يونس","15","وَإِذَا تُتۡلَىٰ عَلَيۡهِمۡ ءَايَاتُنَا بَيِّنَٰتٖ قَالَ ٱلَّذِينَ لَا يَرۡجُونَ لِقَآءَنَا ٱئۡتِ بِقُرۡءَانٍ غَيۡرِ هَٰذَآ أَوۡ بَدِّلۡهُۚ قُلۡ مَا يَكُونُ لِيٓ أَنۡ أُبَدِّلَهُۥ مِن تِلۡقَآيِٕ نَفۡسِيٓۖ إِنۡ أَتَّبِعُ إِلَّا مَا يُوحَىٰٓ إِلَيَّۖ إِنِّيٓ أَخَافُ إِنۡ عَصَيۡتُ رَبِّي عَذَابَ يَوۡمٍ عَظِيمٖ ١٥","وإذا تتلى عليهم آياتنا بينات قال الذين لا يرجون لقاءنا ائت بقرآن غير هذا أو بدله قل ما يكون لي أن أبدله من تلقاء نفسي إن أتبع إلا ما يوحى إلي إني أخاف إن عصيت ربي عذاب يوم عظيم","އަދި އެއުރެންނަށް ތިމަންރަސްކަލާނގެ އާޔަތްތައް ބަޔާން ވެގެންވާ ގޮތުގައި ކިޔަވައިދެއްވާހިނދު، ތިމަންރަސްކަލާނގެއާ ބައްދަލުވުމަށް ނޭދޭމީހުން ބުނެތެވެ. ތިޔަނޫން އެހެން ގުރްއާނެއް ގެނެސްދެއްވާށެވެ! ނުވަތަ އެ ގުރްއާނަށް ބަދަލުގެނެސް ދެއްވާށެވެ! ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނު އަމިއްލަފުޅަށް އެ ބަދަލުކުރުމަކީ، ތިމަންކަލޭގެފާނަށް އޮތްކަމެއް ނޫނެވެ. ތިމަންކަލޭގެފާނަށް އިއްވަވާ ވަހީއަށް މެނުވީ، ތިމަންކަލޭގެފާނު ތަބާ ވެވަޑައެއް ނުގަންނަވަމެވެ. ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް ތިމަންކަލޭގެފާނު އުރެދިއްޖެނަމަ، ބޮޑުވެގެންވާ ދުވަހެއްގެ އަޒާބަށް ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނު ބިރުވެތިވެވަޑައިގަންނަވަމެވެ.","",""],["₁₀ سورة يونس","16","قُل لَّوۡ شَآءَ ٱللَّهُ مَا تَلَوۡتُهُۥ عَلَيۡكُمۡ وَلَآ أَدۡرَىٰكُم بِهِۦۖ فَقَدۡ لَبِثۡتُ فِيكُمۡ عُمُرٗا مِّن قَبۡلِهِۦٓۚ أَفَلَا تَعۡقِلُونَ ١٦","قل لو شاء الله ما تلوته عليكم ولا أدراكم به فقد لبثت فيكم عمرا من قبله أفلا تعقلون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲ އިރާދަކުރެއްވިނަމަ، ތިމަންކަލޭގެފާނު އެ އާޔަތްތައް ތިޔަބައިމީހުންނަށް ކިޔައެއް ނުދެއްވީމުހެވެ. އަދި އެކަލާނގެ ތިޔަބައިމީހުންނަށް އެ އާޔަތް ތަކެއް ނުވެސް އެންގެވީހެވެ. ފަހެ، މީގެކުރިން ތިޔަބައިމީހުންގެ ތެރޭގައި އެތައްދުވަހެއް ވަންދެން (އެބަހީ: ސާޅީސް އަހަރު ވަންދެން) ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނު ހުންނެވީމެވެ. (މިބާވަތުގެ ވާހަކައެއް ނުދައްކަވަމެވެ.) ފަހެ، ތިޔަބައިމީހުންނަކަށް ނުވިސްނޭހެއްޔެވެ؟","",""],["₁₀ سورة يونس","17","فَمَنۡ أَظۡلَمُ مِمَّنِ ٱفۡتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَوۡ كَذَّبَ بِـَٔايَٰتِهِۦٓۚ إِنَّهُۥ لَا يُفۡلِحُ ٱلۡمُجۡرِمُونَ ١٧","فمن أظلم ممن افترى على الله كذبا أو كذب بآياته إنه لا يفلح المجرمون","ﷲއާމެދު ހަދައިގެން ދޮގެއް ބުނިމީހަކަށްވުރެ، ނުވަތަ އެކަލާނގެ އާޔަތްތައް ދޮގުކުޅަ މީހަކަށްވުރެ، އަނިޔާވެރިކަންބޮޑު މީހަކީ ފަހެ، ކާކުހެއްޔެވެ؟ ހަމަކަށަވަރުން، ކުށްކުރާ މީހުން ނުދިނޭނެތެވެ.","",""],["₁₀ سورة يونس","18","وَيَعۡبُدُونَ مِن دُونِ ٱللَّهِ مَا لَا يَضُرُّهُمۡ وَلَا يَنفَعُهُمۡ وَيَقُولُونَ هَـٰٓؤُلَآءِ شُفَعَـٰٓؤُنَا عِندَ ٱللَّهِۚ قُلۡ أَتُنَبِّـُٔونَ ٱللَّهَ بِمَا لَا يَعۡلَمُ فِي ٱلسَّمَٰوَٰتِ وَلَا فِي ٱلۡأَرۡضِۚ سُبۡحَٰنَهُۥ وَتَعَٰلَىٰ عَمَّا يُشۡرِكُونَ ١٨","ويعبدون من دون الله ما لا يضرهم ولا ينفعهم ويقولون هؤلاء شفعاؤنا عند الله قل أتنبئون الله بما لا يعلم في السماوات ولا في الأرض سبحانه وتعالى عما يشركون","އެއުރެން ﷲ ފިޔަވައި އަޅުކަންކުރަނީ، އެއުރެންނަށް ގެއްލުމެއްވެސް ނުދެވޭ، އަދި އެއުރެންނަށް މަންފާއެއްވެސް ނުދެވޭ ތަކެއްޗަށެވެ. އަދި އެއުރެން ބުނެތެވެ. މި ތަކެއްޗަކީ، ﷲގެ ހަޒުރަތުގައި ތިމަންމެންނަށް ޝަފާއަތް ތެރިވާނޭ ތަކެއްޗެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އުޑުތަކުގައިވެސް، އަދި ބިމުގައިވެސް ﷲ ދެނެވޮޑިގެންނުވާ ކަމެއްގެ ވާހަކައިން ތިޔަބައިމީހުން އެކަލާނގެއަށް ޚަބަރު ދެނީހެއްޔެވެ؟ އެއުރެން އެ ޝަރީކުކުރާ ތަކެތިން އެކަލާނގެ ހުސްތާހިރުވެ މަތިވެރިވެވޮޑިގެންވެއެވެ.","",""],["₁₀ سورة يونس","19","وَمَا كَانَ ٱلنَّاسُ إِلَّآ أُمَّةٗ وَٰحِدَةٗ فَٱخۡتَلَفُواْۚ وَلَوۡلَا كَلِمَةٞ سَبَقَتۡ مِن رَّبِّكَ لَقُضِيَ بَيۡنَهُمۡ فِيمَا فِيهِ يَخۡتَلِفُونَ ١٩","وما كان الناس إلا أمة واحدة فاختلفوا ولولا كلمة سبقت من ربك لقضي بينهم فيما فيه يختلفون","އަދި މީސްތަކުން (އެންމެފުރަތަމަ) އެއް އުއްމަތެއްކަމުގައި މެނުވީ ނުވެއެވެ. ދެން (އެއަށްފަހު) އެއުރެން ޚިލާފު ވޫއެވެ. ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން (ޖަޒާދެއްވުން ގިޔާމަތް ދުވަހަށް ފަސްކުރެއްވުމުގެ) ބަސްފުޅެއް އިސްވެފައި ނުވާނަމަ، އެކަންތަކާ ދޭތެރޭ އެއުރެން ޚިލާފުވާ ކަންތަކާމެދު (ދުނިޔެމަތީގައި) އެއުރެންގެ މެދުގައި ނިޔާކުރެއްވީހެވެ.","",""],["₁₀ سورة يونس","20","وَيَقُولُونَ لَوۡلَآ أُنزِلَ عَلَيۡهِ ءَايَةٞ مِّن رَّبِّهِۦۖ فَقُلۡ إِنَّمَا ٱلۡغَيۡبُ لِلَّهِ فَٱنتَظِرُوٓاْ إِنِّي مَعَكُم مِّنَ ٱلۡمُنتَظِرِينَ ٢٠","ويقولون لولا أنزل عليه آية من ربه فقل إنما الغيب لله فانتظروا إني معكم من المنتظرين","އަދި އެއުރެން ބުނެތެވެ. އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އެކަލޭގެފާނަށް މުއުޖިޒާއެއް ބާވައިލައްވާފައި ނުވަނީ ކީއްވެގެންބާވައެވެ! ފަހެ، ކަލޭގެފާނު ވިދާޅުވާށެވެ! ޣައިބުތައް ދެނެވޮޑިގަތުންވާކަން ކަށަވަރީ، ﷲއަށެވެ. ފަހެ، ތިޔަބައިމީހުން އިންތިޒާރުކުރާށެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުވެސް ތިޔަބައިމީހުންނާއެކު އިންތިޒާރުކުރާ މީހުންގެ ތެރެއިން ވާހުށީމެވެ.","",""],["₁₀ سورة يونس","21","وَإِذَآ أَذَقۡنَا ٱلنَّاسَ رَحۡمَةٗ مِّنۢ بَعۡدِ ضَرَّآءَ مَسَّتۡهُمۡ إِذَا لَهُم مَّكۡرٞ فِيٓ ءَايَاتِنَاۚ قُلِ ٱللَّهُ أَسۡرَعُ مَكۡرًاۚ إِنَّ رُسُلَنَا يَكۡتُبُونَ مَا تَمۡكُرُونَ ٢١","وإذا أذقنا الناس رحمة من بعد ضراء مستهم إذا لهم مكر في آياتنا قل الله أسرع مكرا إن رسلنا يكتبون ما تمكرون","އަދި މީސްތަކުންނަށް ތަދުމަޑު ޙާލެއް ޖެހުމަށްފަހު، އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ރަހުމަތް ލައްވައި، ތިޔާގިކަމުގެ ރަހަ ދައްކަވާހިނދު، ތިމަންރަސްކަލާނގެ އާޔަތްތައް އެއުރެން ދޮގުކޮށް މަކަރު ހަދަތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއުރެންގެ މަކަރު ރައްދުކުރެއްވުމުގައި، ﷲ އަވަސްވެވޮޑިގަތުން ބޮޑެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ މަލާއިކަތުން ތިޔަބައިމީހުން ހަދާ މަކަރުތައް ލިޔުއްވަތެވެ.","",""],["₁₀ سورة يونس","22","هُوَ ٱلَّذِي يُسَيِّرُكُمۡ فِي ٱلۡبَرِّ وَٱلۡبَحۡرِۖ حَتَّىٰٓ إِذَا كُنتُمۡ فِي ٱلۡفُلۡكِ وَجَرَيۡنَ بِهِم بِرِيحٖ طَيِّبَةٖ وَفَرِحُواْ بِهَا جَآءَتۡهَا رِيحٌ عَاصِفٞ وَجَآءَهُمُ ٱلۡمَوۡجُ مِن كُلِّ مَكَانٖ وَظَنُّوٓاْ أَنَّهُمۡ أُحِيطَ بِهِمۡ دَعَوُاْ ٱللَّهَ مُخۡلِصِينَ لَهُ ٱلدِّينَ لَئِنۡ أَنجَيۡتَنَا مِنۡ هَٰذِهِۦ لَنَكُونَنَّ مِنَ ٱلشَّـٰكِرِينَ ٢٢","هو الذي يسيركم في البر والبحر حتى إذا كنتم في الفلك وجرين بهم بريح طيبة وفرحوا بها جاءتها ريح عاصف وجاءهم الموج من كل مكان وظنوا أنهم أحيط بهم دعوا الله مخلصين له الدين لئن أنجيتنا من هذه لنكونن من الشاكرين","އެކަލާނގެއީ، އެއްގަމާއި، ކަނޑުގައި، ތިޔަބައިމީހުން ދަތުރުކުރާގޮތް ހިންމަވައިދެއްވާ ރަސްކަލާނގެއެވެ. ދެން ތިޔަބައިމީހުން، ނަވަށް އަރައި ނަލަ ރޯޅިއަކާއެކު އެއުރެންނާއިގެން އެ ނައު ދުއްވައިގަތުމުން، އެކަމާ އެއުރެން އުފާކޮށްކޮށް ތިއްބައި، އެ ނަވަށް ޖެހުނުގަދަ ކޮޅިގަނޑަކުން ހުރިހާ ފަރާތަކުން އެއުރެންނާ ދިމާޔަށް ރާޅުތައް އައިސް އެއުރެން ހަލާކުވެދާނެހެން ހީވީމާ، އެކަލާނގެއަށް އީމާން ކަން ޚާލިސްކުރާ ޙާލުގައި، ﷲއަށް އެއުރެން ދުއާކުރެތެވެ. މިކަމުން، އިބަރަސްކަލާނގެ އަޅަމެން ސަލާމަތްކުރައްވައިފިނަމަ، ހަމަކަށަވަރުން، ޝުކުރުކުރާ މީހުންގެ ތެރެއިން އަޅަމެން ވާހުށީމުއެވެ.","",""],["₁₀ سورة يونس","23","فَلَمَّآ أَنجَىٰهُمۡ إِذَا هُمۡ يَبۡغُونَ فِي ٱلۡأَرۡضِ بِغَيۡرِ ٱلۡحَقِّۗ يَـٰٓأَيُّهَا ٱلنَّاسُ إِنَّمَا بَغۡيُكُمۡ عَلَىٰٓ أَنفُسِكُمۖ مَّتَٰعَ ٱلۡحَيَوٰةِ ٱلدُّنۡيَاۖ ثُمَّ إِلَيۡنَا مَرۡجِعُكُمۡ فَنُنَبِّئُكُم بِمَا كُنتُمۡ تَعۡمَلُونَ ٢٣","فلما أنجاهم إذا هم يبغون في الأرض بغير الحق يا أيها الناس إنما بغيكم على أنفسكم متاع الحياة الدنيا ثم إلينا مرجعكم فننبئكم بما كنتم تعملون","ދެން އެކަލާނގެ އެއުރެން ސަލާމަތްކުރެއްވި ހިނދު، އެހާރުން، ހައްގަކާނުލައި، އެއުރެން ބިމުގައި ފަސާދަ އުފައްދައި ދެކޮޅުވެރިވެތެވެ. އޭ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ ދެކޮޅުވެރިކަމުގެ ގެއްލުން ހުރިކަންކަށަވަރީ، ހަމަ ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސު ތަކަށެވެ. ދުނިޔޭގެ ދިރިއުޅުމުގެ ވަގުތީ އުފަލެއްގެ ގޮތުގައެވެ. ދެން ތިޔަބައިމީހުން ރުޖޫއަ ވާހުށީ، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށެވެ. އޭރުން ތިޔަބައިމީހުން ކޮށްއުޅުނު ކަންތަކުގެ ޚަބަރު، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް އަންގަވާހުށީމެވެ.","",""],["₁₀ سورة يونس","24","إِنَّمَا مَثَلُ ٱلۡحَيَوٰةِ ٱلدُّنۡيَا كَمَآءٍ أَنزَلۡنَٰهُ مِنَ ٱلسَّمَآءِ فَٱخۡتَلَطَ بِهِۦ نَبَاتُ ٱلۡأَرۡضِ مِمَّا يَأۡكُلُ ٱلنَّاسُ وَٱلۡأَنۡعَٰمُ حَتَّىٰٓ إِذَآ أَخَذَتِ ٱلۡأَرۡضُ زُخۡرُفَهَا وَٱزَّيَّنَتۡ وَظَنَّ أَهۡلُهَآ أَنَّهُمۡ قَٰدِرُونَ عَلَيۡهَآ أَتَىٰهَآ أَمۡرُنَا لَيۡلًا أَوۡ نَهَارٗا فَجَعَلۡنَٰهَا حَصِيدٗا كَأَن لَّمۡ تَغۡنَ بِٱلۡأَمۡسِۚ كَذَٰلِكَ نُفَصِّلُ ٱلۡأٓيَٰتِ لِقَوۡمٖ يَتَفَكَّرُونَ ٢٤","إنما مثل الحياة الدنيا كماء أنزلناه من السماء فاختلط به نبات الأرض مما يأكل الناس والأنعام حتى إذا أخذت الأرض زخرفها وازينت وظن أهلها أنهم قادرون عليها أتاها أمرنا ليلا أو نهارا فجعلناها حصيدا كأن لم تغن بالأمس كذلك نفصل الآيات لقوم يتفكرون","ދުނިޔޭގެ ދިރިއުޅުމުގެ މިސާލު ވާކަން ކަށަވަރީ، ތިމަންރަސްކަލާނގެ އުޑުން ވެއްސެވި ފެނެއްގެ މިސާލުކަމުގައެވެ. ފަހެ، އިންސާނުންނާއި، ނަޢަމް ސޫފި ކައިއުޅޭ ބާވަތްތަކުގެ ތެރެއިން ބިމުގެ ގަސްގަހާގެހި، އެ ވާރޭފެނާއެކުވެ، އެންމެފަހުން އެ ބިމަށް ރީތިކަމާއި، އާރޯކަންލިބި (މާމެލާމެއްޔާއި މޭވާތަކުން) ޒީނަތްތެރިވެ، އެ ބިމުގެ އަހުލުވެރިން އެ ތަކެތީގެ މައްޗަށް ބާރު ހިންގުމަށް ކުޅަދާނަވެގެންވާކަމަށް ހީކޮށްގެން ތިއްބައި (އެތަކެތި ހަލާކުވެދިއުމަށް) ރޭގަނޑެއްގައި، ނުވަތަ ދުވާލެއްގައި، ތިމަންރަސްކަލާނގެ އަމުރުފުޅު އައެވެ. ފަހެ، އެހިނދު ކޮށާލައިފައިވާ ގޮވާންތަކެއް ފަދައިން، ތިމަންރަސްކަލާނގެ އެތަކެތި ލެއްވީމެވެ. އެތަކެތި އިއްޔެ ނުވެސް ނެތްކަހަލައެވެ. ފިކުރުކުރާ ބަޔަކަށް، ތިމަންރަސްކަލާނގެ އާޔަތްތައް ތަފްޞީލު ކޮށްދެއްވަނީ އެފަދައިންނެވެ.","",""],["₁₀ سورة يونس","25","وَٱللَّهُ يَدۡعُوٓاْ إِلَىٰ دَارِ ٱلسَّلَٰمِ وَيَهۡدِي مَن يَشَآءُ إِلَىٰ صِرَٰطٖ مُّسۡتَقِيمٖ ٢٥","والله يدعو إلى دار السلام ويهدي من يشاء إلى صراط مستقيم","ﷲ ގޮވައިލައްވަނީ، ސަލާމަތުގެ ގޮވައްޗަށެވެ. (އެބަހީ: ސުވަރުގެއަށެވެ.) އަދި އެކަލާނގެ އިރާދަކުރައްވާ ބަޔަކަށް، ސީދާވެގެންވާ ތެދުމަގަށް އެކަލާނގެ މަގު ދައްކަވަތެވެ.","",""],["₁₀ سورة يونس","26","۞لِّلَّذِينَ أَحۡسَنُواْ ٱلۡحُسۡنَىٰ وَزِيَادَةٞۖ وَلَا يَرۡهَقُ وُجُوهَهُمۡ قَتَرٞ وَلَا ذِلَّةٌۚ أُوْلَـٰٓئِكَ أَصۡحَٰبُ ٱلۡجَنَّةِۖ هُمۡ فِيهَا خَٰلِدُونَ ٢٦","للذين أحسنوا الحسنى وزيادة ولا يرهق وجوههم قتر ولا ذلة أولئك أصحاب الجنة هم فيها خالدون","ހެޔޮ ޢަމަލުކުޅަމީހުންނަށް، އެންމެހެޔޮ ޖަޒާ ހުށްޓެވެ. (އެއީ ސުވަރުގެއެވެ.) އަދި އޭގެއިތުރަށްވެސް ހުށްޓެވެ. (އެއީ ﷲގެ ވަޖުހުފުޅު ދެއްކެވުމެވެ.) އަދި އެއުރެންގެ މޫނުތަކަކަށް ހިރަފުހެއް ނުވަތަ ދެރަކަމެއް ނާރާނެތެވެ. އެއުރެންނަކީ، ސުވަރުގޭގެ އަހުލުވެރިންނެވެ. އެއުރެން އެތާނގައި ދެމިތިބޭ ހުށްޓެވެ.","",""],["₁₀ سورة يونس","27","وَٱلَّذِينَ كَسَبُواْ ٱلسَّيِّـَٔاتِ جَزَآءُ سَيِّئَةِۭ بِمِثۡلِهَا وَتَرۡهَقُهُمۡ ذِلَّةٞۖ مَّا لَهُم مِّنَ ٱللَّهِ مِنۡ عَاصِمٖۖ كَأَنَّمَآ أُغۡشِيَتۡ وُجُوهُهُمۡ قِطَعٗا مِّنَ ٱلَّيۡلِ مُظۡلِمًاۚ أُوْلَـٰٓئِكَ أَصۡحَٰبُ ٱلنَّارِۖ هُمۡ فِيهَا خَٰلِدُونَ ٢٧","والذين كسبوا السيئات جزاء سيئة بمثلها وترهقهم ذلة ما لهم من الله من عاصم كأنما أغشيت وجوههم قطعا من الليل مظلما أولئك أصحاب النار هم فيها خالدون","އަދި ނުބައި ޢަމަލުތައް ކުރި މީހުންނަށްހުރީ، ކޮންމެ ނުބައިކަމަކަށް އެފަދަ ޖަޒާއެވެ. އަދި އެއުރެންގެ މައްޗަށް ފެތުރިފައިވަނީ ނިކަމެތިކަމެވެ. ﷲގެ އަޒާބުން ރައްކާތެރިކުރާނޭ އެއްވެސް ފަރާތެއް އެއުރެންނަކަށް ނުވެއެވެ. އެއުރެންގެ މޫނުތައް، ކަޅު އަނދިރި ރޭގަނޑުން ބައެއްލައްވައި ނިވާކުރައްވާފައިވާ ކަހަލައެވެ. އެއުރެންނަކީ، ނަރަކައިގެ އަހުލުވެރިންނެވެ. އެއުރެން އެތާނގައި ދެމިތިބޭހުށްޓެވެ.","",""],["₁₀ سورة يونس","28","وَيَوۡمَ نَحۡشُرُهُمۡ جَمِيعٗا ثُمَّ نَقُولُ لِلَّذِينَ أَشۡرَكُواْ مَكَانَكُمۡ أَنتُمۡ وَشُرَكَآؤُكُمۡۚ فَزَيَّلۡنَا بَيۡنَهُمۡۖ وَقَالَ شُرَكَآؤُهُم مَّا كُنتُمۡ إِيَّانَا تَعۡبُدُونَ ٢٨","ويوم نحشرهم جميعا ثم نقول للذين أشركوا مكانكم أنتم وشركاؤكم فزيلنا بينهم وقال شركاؤهم ما كنتم إيانا تعبدون","ތިމަންރަސްކަލާނގެ އެއުރެން އެންމެން އެއްތަނަކަށް އެއްކުރައްވާ ދުވަސް (ހަނދުމަކުރާށެވެ!) ދެން ޝަރީކުކުޅަ މީހުންނަށް، ތިމަންރަސްކަލާނގެ ވަހީކުރައްވާހުށީމެވެ. ތިޔަބައިމީހުންނާއި، ތިޔަބައިމީހުން ޝަރީކުކުޅަ ތަކެތި ތިބިތާނގައި ތިބޭށެވެ! ފަހެ، އެއުރެންގެ މެދުގައިވާ ގުޅުންތައް ތިމަންރަސްކަލާނގެ ވަނީ ކަނޑުއްވައި ވަކިކުރައްވާފައެވެ. އަދި އެއުރެން ޝަރީކުކުޅަ ތަކެތި ބުނާނެތެވެ. ތިޔަބައިމީހުން އަޅުކަންކޮށް އުޅުނީ ތިމަންމެންނަކަށް ނޫނެވެ.","",""],["₁₀ سورة يونس","29","فَكَفَىٰ بِٱللَّهِ شَهِيدَۢا بَيۡنَنَا وَبَيۡنَكُمۡ إِن كُنَّا عَنۡ عِبَادَتِكُمۡ لَغَٰفِلِينَ ٢٩","فكفى بالله شهيدا بيننا وبينكم إن كنا عن عبادتكم لغافلين","ފަހެ، ތިމަންމެންނާއި، ތިޔަބައިމީހުންނާ ދެމެދުގައި ހެތްކަކަށް ﷲ ފުދެއެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ކުޅަ އަޅުކަމުން ތިމަންމެންވަނީ ޣާފިލު ވެގެންނެވެ.","",""],["₁₀ سورة يونس","30","هُنَالِكَ تَبۡلُواْ كُلُّ نَفۡسٖ مَّآ أَسۡلَفَتۡۚ وَرُدُّوٓاْ إِلَى ٱللَّهِ مَوۡلَىٰهُمُ ٱلۡحَقِّۖ وَضَلَّ عَنۡهُم مَّا كَانُواْ يَفۡتَرُونَ ٣٠","هنالك تبلو كل نفس ما أسلفت وردوا إلى الله مولاهم الحق وضل عنهم ما كانوا يفترون","އެތާނގައި ކޮންމެ ނަފްސަކަށްމެ، އެ ނަފްސެއް އިސްކުޅަ ޢަމަލެއްގެގޮތް އެނގޭނެތެވެ. އަދި އެއުރެންގެ އެހީތެރިވަންތަ، ހައްގުވަންތަ ﷲގެ ހަޒުރަތަށް އެއުރެން ރައްދުކުރައްވާނެތެވެ. އަދި އެއުރެން ދޮގުން އުފައްދައިގެން އުޅުނު ކަންތައްތައް، އެއުރެންގެ ކިބައިން ގެއްލިގެން ހިނގައިދާނެތެވެ.","",""],["₁₀ سورة يونس","31","قُلۡ مَن يَرۡزُقُكُم مِّنَ ٱلسَّمَآءِ وَٱلۡأَرۡضِ أَمَّن يَمۡلِكُ ٱلسَّمۡعَ وَٱلۡأَبۡصَٰرَ وَمَن يُخۡرِجُ ٱلۡحَيَّ مِنَ ٱلۡمَيِّتِ وَيُخۡرِجُ ٱلۡمَيِّتَ مِنَ ٱلۡحَيِّ وَمَن يُدَبِّرُ ٱلۡأَمۡرَۚ فَسَيَقُولُونَ ٱللَّهُۚ فَقُلۡ أَفَلَا تَتَّقُونَ ٣١","قل من يرزقكم من السماء والأرض أمن يملك السمع والأبصار ومن يخرج الحي من الميت ويخرج الميت من الحي ومن يدبر الأمر فسيقولون الله فقل أفلا تتقون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންނަށް އުޑުންނާއި، ބިމުން ރިޒްގު ދެއްވަނީ ކާކުހެއްޔެވެ؟ ނުވަތަ އިވުމާއި ފެނުން މަލަކަ ވެގެންވަނީ ކާކަށްހެއްޔެވެ؟ އަދި މަރުވެފައިވާ ތަކެތިން، ދިރޭތަކެތި ނެރުއްވައި، ދިރޭތަކެތިން މަރުވެފައިވާ ތަކެތި ނެރުއްވަނީ ކާކުހެއްޔެވެ؟ އަދި އެންމެހާ ކަންތައް ތަދްބީރުކުރައްވަނީ ކާކުހެއްޔެވެ؟ ފަހެ، އެއުރެން ބުނާނެތެވެ. (އެއީ) ﷲއެވެ. ދެން ކަލޭގެފާނު ވިދާޅުވާށެވެ! ފަހެ، ތިޔަބައިމީހުން (އެކަލާނގެއަށް) ތަގުވާވެރި ނުވަނީހެއްޔެވެ؟","",""],["₁₀ سورة يونس","32","فَذَٰلِكُمُ ٱللَّهُ رَبُّكُمُ ٱلۡحَقُّۖ فَمَاذَا بَعۡدَ ٱلۡحَقِّ إِلَّا ٱلضَّلَٰلُۖ فَأَنَّىٰ تُصۡرَفُونَ ٣٢","فذلكم الله ربكم الحق فماذا بعد الحق إلا الضلال فأنى تصرفون","ފަހެ، އެއީ ﷲއެވެ. ތިޔަބައިމީހުންގެ ވެރި، ހައްގުވަންތަ ރަސްކަލާނގެއެވެ. ފަހެ، ހައްގު ގޮތަށްފަހުގައި ވަނީ މަގުފުރެދުންނޫން ކޮންއެއްޗެއް ހެއްޔެވެ؟ (އެބަހީ: ހައްގު ގޮތުން އެއްކިބާވެއްޖެނަމަ، ދެން ދެވޭނީ ފުރެދުމުގެ ތެރެއަށެވެ.) ފަހެ، ތިޔަބައިމީހުން (ހައްގު ގޮތް ފިޔަވައި) އެނބުރިދަނީ، ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["₁₀ سورة يونس","33","كَذَٰلِكَ حَقَّتۡ كَلِمَتُ رَبِّكَ عَلَى ٱلَّذِينَ فَسَقُوٓاْ أَنَّهُمۡ لَا يُؤۡمِنُونَ ٣٣","كذلك حقت كلمت ربك على الذين فسقوا أنهم لا يؤمنون","ފާސިގުވި މީހުންގެ މައްޗަށް، އެއުރެން އީމާން ނުވާނެކަމަށް ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ކަލިމަފުޅު ހަމައެފަދައިންވަނީ ހައްގު ވެގެންނެވެ.","",""],["₁₀ سورة يونس","34","قُلۡ هَلۡ مِن شُرَكَآئِكُم مَّن يَبۡدَؤُاْ ٱلۡخَلۡقَ ثُمَّ يُعِيدُهُۥۚ قُلِ ٱللَّهُ يَبۡدَؤُاْ ٱلۡخَلۡقَ ثُمَّ يُعِيدُهُۥۖ فَأَنَّىٰ تُؤۡفَكُونَ ٣٤","قل هل من شركائكم من يبدأ الخلق ثم يعيده قل الله يبدأ الخلق ثم يعيده فأنى تؤفكون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ޝަރީކުކުރާ ފަރާތްތަކުގެ ތެރޭގައި (ނެތުމުގެތެރެއިން) ޚަލްގު ތަކުން އަލަށް އުފައްދައި، ދެން އަލުން އެ ޚަލްގު ތަކުން އިއާދަކުރާ މީހަކު ވޭހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! (ނެތުމުގެތެރެއިން) ޚަލްގު ތަކުން އަލަށް އުފައްދަވައި، ދެން އަލުން އެ ޚަލްގު ތަކުން އިއާދަކުރައްވަނީ ﷲއެވެ. ފަހެ، ތިޔަބައިމީހުން (އީމާންކަމުން) އެއްކިބާވެގަންނަނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["₁₀ سورة يونس","35","قُلۡ هَلۡ مِن شُرَكَآئِكُم مَّن يَهۡدِيٓ إِلَى ٱلۡحَقِّۚ قُلِ ٱللَّهُ يَهۡدِي لِلۡحَقِّۗ أَفَمَن يَهۡدِيٓ إِلَى ٱلۡحَقِّ أَحَقُّ أَن يُتَّبَعَ أَمَّن لَّا يَهِدِّيٓ إِلَّآ أَن يُهۡدَىٰۖ فَمَا لَكُمۡ كَيۡفَ تَحۡكُمُونَ ٣٥","قل هل من شركائكم من يهدي إلى الحق قل الله يهدي للحق أفمن يهدي إلى الحق أحق أن يتبع أمن لا يهدي إلا أن يهدى فما لكم كيف تحكمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ޝަރީކުކުރާ ފަރާތްތަކުގެ ތެރޭގައި ހައްގަށް މަގުދައްކާ މީހަކު ވޭހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހައްގަށް މަގުދައްކަވަނީ ﷲއެވެ. ފަހެ، ތަބާ ވުން ހައްގު ކަންބޮޑީ ހައްގަށް މަގުދައްކާ ފަރާތަކާ ހެއްޔެވެ؟ ނުވަތަ މަގުދައްކަވައިގެން މެނުވީ ތެދުމަގު ލިބިނުގަނެވޭ މީހަކާ ހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުންނަށް ތިޔަ ތިބީ ކީއްވެފައި ހެއްޔެވެ؟ ތިޔަބައިމީހުން ހުކުމްކުރަނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["₁₀ سورة يونس","36","وَمَا يَتَّبِعُ أَكۡثَرُهُمۡ إِلَّا ظَنًّاۚ إِنَّ ٱلظَّنَّ لَا يُغۡنِي مِنَ ٱلۡحَقِّ شَيۡـًٔاۚ إِنَّ ٱللَّهَ عَلِيمُۢ بِمَا يَفۡعَلُونَ ٣٦","وما يتبع أكثرهم إلا ظنا إن الظن لا يغني من الحق شيئا إن الله عليم بما يفعلون","އެއުރެންކުރެ ގިނަމީހުން ހީއަކާމެނުވީ ތަބައެއް ނުވެތެވެ. ހަމަކަށަވަރުން، ހީއަކީ ހައްގުގެ ބަދަލުގައި އެއްވެސްކަމެއް ފުއްދައިދޭނޭ އެއްޗެއްނޫނެވެ. ހަމަކަށަވަރުން، ﷲއީ، އެއުރެން ކުރާ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₁₀ سورة يونس","37","وَمَا كَانَ هَٰذَا ٱلۡقُرۡءَانُ أَن يُفۡتَرَىٰ مِن دُونِ ٱللَّهِ وَلَٰكِن تَصۡدِيقَ ٱلَّذِي بَيۡنَ يَدَيۡهِ وَتَفۡصِيلَ ٱلۡكِتَٰبِ لَا رَيۡبَ فِيهِ مِن رَّبِّ ٱلۡعَٰلَمِينَ ٣٧","وما كان هذا القرآن أن يفترى من دون الله ولكن تصديق الذي بين يديه وتفصيل الكتاب لا ريب فيه من رب العالمين","ﷲ ނޫންފަރާތަކުން ހަދައިގެން ގެންނަ އެއްޗަކަށް މި ގުރްއާން ނުވެއެވެ. އެހެނެއްކަމަކު (އެ ގުރްއާން ބާވައިލެއްވީ) އޭގެކުރީގައިވާ ފޮތްތައް ތެދުކުރުމަށާއި، ފޮތުގައިވާ ހުކުމްތައް ތަފްޞީލު ކޮށްދެއްވުމަށެވެ. އެ ފޮތާމެދު ޝައްކެއް ނެތެވެ. (އެ ފޮތް ބާވައިލެއްވީ) އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުންނެވެ.","",""],["₁₀ سورة يونس","38","أَمۡ يَقُولُونَ ٱفۡتَرَىٰهُۖ قُلۡ فَأۡتُواْ بِسُورَةٖ مِّثۡلِهِۦ وَٱدۡعُواْ مَنِ ٱسۡتَطَعۡتُم مِّن دُونِ ٱللَّهِ إِن كُنتُمۡ صَٰدِقِينَ ٣٨","أم يقولون افتراه قل فأتوا بسورة مثله وادعوا من استطعتم من دون الله إن كنتم صادقين","އަދި ކިއެއްތަ! (އެ ގުރްއާން (އެއީ، އެކަލޭގެފާނު ހައްދަވައިގެން އުޅުއްވާ އެއްޗެއްކަމަށް އެއުރެން ބުނަނީހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ފަހެ، ތިޔަބައިމީހުން ތެދުވެރިން ކަމުގައިވަނީނަމަ، ﷲ ފިޔަވައި ތިޔަބައިމީހުންނަށް ކުޅަދާނަވީހައި ބަޔަކަށް ގޮވައިގެން ނަމަވެސް، އެއާ އެއްފަދަ ސޫރަތެއް ނިކަން ގެނެސްބަލާށެވެ!","",""],["₁₀ سورة يونس","39","بَلۡ كَذَّبُواْ بِمَا لَمۡ يُحِيطُواْ بِعِلۡمِهِۦ وَلَمَّا يَأۡتِهِمۡ تَأۡوِيلُهُۥۚ كَذَٰلِكَ كَذَّبَ ٱلَّذِينَ مِن قَبۡلِهِمۡۖ فَٱنظُرۡ كَيۡفَ كَانَ عَٰقِبَةُ ٱلظَّـٰلِمِينَ ٣٩","بل كذبوا بما لم يحيطوا بعلمه ولما يأتهم تأويله كذلك كذب الذين من قبلهم فانظر كيف كان عاقبة الظالمين","އަދި ކިއެއްތަ! އެ ގުރްއާން ގައިވާ އެއްޗެއް އެއުރެންނަށް ނޭނގެނީސް، އަދި އޭގެ މާނަ އެއުރެންނާ ހަމަޔަށް ނާންނަނީސް، އެއުރެން އެ ގުރްއާން ދޮގުކުރޫއެވެ. ހަމަ އެފަދައިން އެއުރެންގެ ކުރީގެ މީހުންވެސް (އެއުރެންގެ ރަސޫލުން) ދޮގުކުރޫއެވެ. ފަހެ، އަނިޔާވެރިންގެ ނިމުންވަނީ، ކޮންފަދައަކުންކަން ކަލޭގެފާނު ދެކެވަޑައި ގަންނަވާށެވެ!","",""],["₁₀ سورة يونس","40","وَمِنۡهُم مَّن يُؤۡمِنُ بِهِۦ وَمِنۡهُم مَّن لَّا يُؤۡمِنُ بِهِۦۚ وَرَبُّكَ أَعۡلَمُ بِٱلۡمُفۡسِدِينَ ٤٠","ومنهم من يؤمن به ومنهم من لا يؤمن به وربك أعلم بالمفسدين","އެއުރެންގެ ތެރޭގައި އެ ގުރްއާނަށް އީމާންވާ ބަޔަކުވެއެވެ. އަދި އެއުރެންގެ ތެރޭގައި އެ ގުރްއާނަށް އީމާން ނުވާ ބަޔަކުވެސްވެއެވެ. ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ފަސާދަކުރާމީހުން އެންމެމޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₁₀ سورة يونس","41","وَإِن كَذَّبُوكَ فَقُل لِّي عَمَلِي وَلَكُمۡ عَمَلُكُمۡۖ أَنتُم بَرِيٓـُٔونَ مِمَّآ أَعۡمَلُ وَأَنَا۠ بَرِيٓءٞ مِّمَّا تَعۡمَلُونَ ٤١","وإن كذبوك فقل لي عملي ولكم عملكم أنتم بريئون مما أعمل وأنا بريء مما تعملون","އަދި އެއުރެން ކަލޭގެފާނު ދޮގުކޮށްފިނަމަ، ފަހެ، ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނަށް، ތިމަންކަލޭގެފާނު ކުރެއްވި ޢަމަލެކެވެ. އަދި ތިޔަބައިމީހުންނަށް ތިޔަބައިމީހުން ކުޅަ ޢަމަލެކެވެ. ތިމަންކަލޭގެފާނު ކުރައްވާ ޢަމަލު ތަކުން، ތިޔަބައިމީހުންވަނީ، ބަރީއަވެގެންނެވެ. އަދި ތިޔަބައިމީހުން ކުރާ ޢަމަލު ތަކުން، ތިމަންކަލޭގެފާނު ވަނީ ބަރީއަވެގެންނެވެ.","",""],["₁₀ سورة يونس","42","وَمِنۡهُم مَّن يَسۡتَمِعُونَ إِلَيۡكَۚ أَفَأَنتَ تُسۡمِعُ ٱلصُّمَّ وَلَوۡ كَانُواْ لَا يَعۡقِلُونَ ٤٢","ومنهم من يستمعون إليك أفأنت تسمع الصم ولو كانوا لا يعقلون","އަދި އެއުރެންގެ ތެރޭގައި، ކަލޭގެފާނަށް ކަނުލައިއަހާ މީހުންވެއެވެ. ފަހެ، ބީރުބަޔަކަށް، އެއުރެންނަށް ނުވިސްނޭކަމުގައިވިޔަސް، ކަލޭގެފާނު އިއްވަވަނީތޯއެވެ؟","",""],["₁₀ سورة يونس","43","وَمِنۡهُم مَّن يَنظُرُ إِلَيۡكَۚ أَفَأَنتَ تَهۡدِي ٱلۡعُمۡيَ وَلَوۡ كَانُواْ لَا يُبۡصِرُونَ ٤٣","ومنهم من ينظر إليك أفأنت تهدي العمي ولو كانوا لا يبصرون","އަދި އެއުރެންގެ ތެރޭގައި ކަލޭގެފާނަށް ބަލާމީހުންވެއެވެ. ފަހެ، ކަނުބަޔަކަށް، އެއުރެންނަށް ނުފެންނަކަމުގައިވިޔަސް، ކަލޭގެފާނު މަގުދައްކަވަނީތޯއެވެ؟","",""],["₁₀ سورة يونس","44","إِنَّ ٱللَّهَ لَا يَظۡلِمُ ٱلنَّاسَ شَيۡـٔٗا وَلَٰكِنَّ ٱلنَّاسَ أَنفُسَهُمۡ يَظۡلِمُونَ ٤٤","إن الله لا يظلم الناس شيئا ولكن الناس أنفسهم يظلمون","ހަމަކަށަވަރުން، ﷲ، އެއްވެސްކަމަކުން މީސްތަކުންނަށް އަނިޔާއެއް ނުކުރައްވަތެވެ. އެހެނެއްކަމަކު، މީސްތަކުން އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް އަނިޔާކުރެތެވެ.","",""],["₁₀ سورة يونس","45","وَيَوۡمَ يَحۡشُرُهُمۡ كَأَن لَّمۡ يَلۡبَثُوٓاْ إِلَّا سَاعَةٗ مِّنَ ٱلنَّهَارِ يَتَعَارَفُونَ بَيۡنَهُمۡۚ قَدۡ خَسِرَ ٱلَّذِينَ كَذَّبُواْ بِلِقَآءِ ٱللَّهِ وَمَا كَانُواْ مُهۡتَدِينَ ٤٥","ويوم يحشرهم كأن لم يلبثوا إلا ساعة من النهار يتعارفون بينهم قد خسر الذين كذبوا بلقاء الله وما كانوا مهتدين","އެކަލާނގެ އެއުރެން މަހުޝަރަށް ފޮނުއްވާ ދުވަހު، ދުވާލުން ސާޢަތެއްގެ މިންވަރަށް މެނުވީ (ދުނިޔޭގައި ނުވަތަ ކަށްވަޅުގައި) އެއުރެން ނުތިބޭކަހަލައެވެ. އެއުރެންގެ މެދުގައި ތަޢާރަފް ވާނެތެވެ. ﷲއާ ބައްދަލުވާނޭކަން ދޮގުކުޅަ މީހުން، ގެއްލި ހަލާކުވެއްޖެކަން ކަށަވަރެވެ. އަދި އެއުރެންނީ، ތެދުމަގު ލިބިގެންވާ ބަޔަކު ކަމުގައިވެސް ނުމެވޭމެއެވެ.","",""],["₁₀ سورة يونس","46","وَإِمَّا نُرِيَنَّكَ بَعۡضَ ٱلَّذِي نَعِدُهُمۡ أَوۡ نَتَوَفَّيَنَّكَ فَإِلَيۡنَا مَرۡجِعُهُمۡ ثُمَّ ٱللَّهُ شَهِيدٌ عَلَىٰ مَا يَفۡعَلُونَ ٤٦","وإما نرينك بعض الذي نعدهم أو نتوفينك فإلينا مرجعهم ثم الله شهيد على ما يفعلون","އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ވައުދުކުރެއްވި ބައެއްކަންތައް ކަލޭގެފާނަށް ދެއްކެވިޔަސް، ނުވަތަ (އޭގެކުރިން) ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު މަރުގެންނެވިޔަސް، ފަހެ، އެއުރެންގެ ރުޖޫއަ ވުންވަނީ، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށެވެ. ދެން އެއުރެން ކޮށްއުޅުނު ކަންތަކުގެ މައްޗަށް، ﷲ ހެކިވެވޮޑިގަންނަވާނެތެވެ.","",""],["₁₀ سورة يونس","47","وَلِكُلِّ أُمَّةٖ رَّسُولٞۖ فَإِذَا جَآءَ رَسُولُهُمۡ قُضِيَ بَيۡنَهُم بِٱلۡقِسۡطِ وَهُمۡ لَا يُظۡلَمُونَ ٤٧","ولكل أمة رسول فإذا جاء رسولهم قضي بينهم بالقسط وهم لا يظلمون","އަދި ކޮންމެ އުއްމަތަކަށްވެސް ރަސޫލަކުވެއެވެ. ފަހެ، (ގިޔާމަތް ދުވަހުން) އެ އުއްމަތެއްގެ ރަސޫލަކު ވަޑައިގަތުމުން، އެއުރެންގެ މެދުގައި ޢަދުލަށް ހުކުމްކުރައްވާނެތެވެ. އަދި އެއުރަންނަކަށް ބޭއިންސާފެއް ނުކުރައްވާހުށްޓެވެ.","",""],["₁₀ سورة يونس","48","وَيَقُولُونَ مَتَىٰ هَٰذَا ٱلۡوَعۡدُ إِن كُنتُمۡ صَٰدِقِينَ ٤٨","ويقولون متى هذا الوعد إن كنتم صادقين","އަދި އެއުރެން ބުނެތެވެ. ތިޔަބައިމީހުންނީ ތެދުބުނާ ބަޔަކު ކަމުގައިވާނަމަ، ތިޔަ (ބުނާ އަޒާބުގެ) ވައުދު އަންނާނީ ކޮންއިރަކުން ހެއްޔެވެ؟","",""],["₁₀ سورة يونس","49","قُل لَّآ أَمۡلِكُ لِنَفۡسِي ضَرّٗا وَلَا نَفۡعًا إِلَّا مَا شَآءَ ٱللَّهُۗ لِكُلِّ أُمَّةٍ أَجَلٌۚ إِذَا جَآءَ أَجَلُهُمۡ فَلَا يَسۡتَـٔۡخِرُونَ سَاعَةٗ وَلَا يَسۡتَقۡدِمُونَ ٤٩","قل لا أملك لنفسي ضرا ولا نفعا إلا ما شاء الله لكل أمة أجل إذا جاء أجلهم فلا يستأخرون ساعة ولا يستقدمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނުގެ އަމިއްލަ ނަފްސަށް ގެއްލުމެއް ދިނުމަކީވެސް، އަދި މަންފާއެއް ދިނުމަކީވެސް، ތިމަންކަލޭގެފާނުގެ ބާރުގެ ދަށުގައިވާ ކަމެއްނޫނެވެ. ﷲ އިރާދަކުރެއްވިކަމެއް މެނުވީއެވެ. ކޮންމެ އުއްމަތަކަށްވެސް އަޖަލެއްވެއެވެ. އެއުރެންގެ އަޖަލު އަތުވެއްޖެނަމަ، އެންމެ ސާޢަތެއްގެ އިރުވެސް އެއުރެންނަކަށް ލަހެއްނުކުރައްވާނެތެވެ. އަދި އަވަހެއްވެސް ނުމެކުރައްވާނޭމެއެވެ.","",""],["₁₀ سورة يونس","50","قُلۡ أَرَءَيۡتُمۡ إِنۡ أَتَىٰكُمۡ عَذَابُهُۥ بَيَٰتًا أَوۡ نَهَارٗا مَّاذَا يَسۡتَعۡجِلُ مِنۡهُ ٱلۡمُجۡرِمُونَ ٥٠","قل أرأيتم إن أتاكم عذابه بياتا أو نهارا ماذا يستعجل منه المجرمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ނިކަން ބުނެބަލާށެވެ! ތިޔަބައިމީހުންގެ ގާތަށް އެކަލާނގެ އަޒާބު، ރޭގަނޑު (ނިދާފައި ތިއްބައި) ނުވަތަ ދުވާލު (މަސައްކަތުގައި ތިއްބައި) އަޔަސް (ތިޔަބައިމީހުންނަށް އޮތީ ކޮންފައިދާއެއް ހެއްޔެވެ؟) ކުށްވެރިން (ލަސްވެގެން) އަވަސްވުންއެދި އެއުޅެނީ އެ އަޒާބުގެ ތެރެއިން ކޮންކަމެއް ހެއްޔެވެ؟","",""],["₁₀ سورة يونس","51","أَثُمَّ إِذَا مَا وَقَعَ ءَامَنتُم بِهِۦٓۚ ءَآلۡـَٰٔنَ وَقَدۡ كُنتُم بِهِۦ تَسۡتَعۡجِلُونَ ٥١","أثم إذا ما وقع آمنتم به آلآن وقد كنتم به تستعجلون","އެ އަޒާބު އައިސްޖެހުނީމާ، ދެން ތިޔަބައިމީހުން އެކަލާނގެއަށް އީމާން ވީހެއްޔެވެ؟ (އަދި އަންގަވާނެތެވެ. ތިޔަބައިމީހުން ތިޔަ އީމާން ވަނީ) މިހާރު ހެއްޔެވެ؟ ތިޔަބައިމީހުން (ފުރައްސާރައިގެ ގޮތުން) އެ އަޒާބު (ނައިސް ލަސްވެގެން) އަވަސްވުންއެދި އުޅުނީމުއެވެ.","",""],["₁₀ سورة يونس","52","ثُمَّ قِيلَ لِلَّذِينَ ظَلَمُواْ ذُوقُواْ عَذَابَ ٱلۡخُلۡدِ هَلۡ تُجۡزَوۡنَ إِلَّا بِمَا كُنتُمۡ تَكۡسِبُونَ ٥٢","ثم قيل للذين ظلموا ذوقوا عذاب الخلد هل تجزون إلا بما كنتم تكسبون","ދެން އަނިޔާވެރިވި މީހުންނަށް އަންގަވާނެތެވެ. ދެމިހުންނަނިވި އަޒާބުގެ ރަހަ ތިޔަބައިމީހުން ލިބިގަންނާށެވެ! ތިޔަބައިމީހުން ހޯދައިއުޅުނު ޢަމަލުތަކުގެ ސަބަބުން މެނުވީ، ތިޔަބައިމީހުންނަށް ޖަޒާ ލިބޭހެއްޔެވެ؟","",""],["₁₀ سورة يونس","53","۞وَيَسۡتَنۢبِـُٔونَكَ أَحَقٌّ هُوَۖ قُلۡ إِي وَرَبِّيٓ إِنَّهُۥ لَحَقّٞۖ وَمَآ أَنتُم بِمُعۡجِزِينَ ٥٣","ويستنبئونك أحق هو قل إي وربي إنه لحق وما أنتم بمعجزين","އެއީ، ހަމަ ހައްގު ތެދުތޯ ޚަބަރު ދެއްވުމަށް، ކަލޭގެފާނުގެ ކިބައިން އެއުރެން އެދޭނެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އާނއެކެވެ! ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ގަންދެއްވައި ވިދާޅުވަމެވެ. ހަމަކަށަވަރުން، އެއީ، ހަމަ ހައްގު ތެދެވެ. އަދި ތިޔަބައިމީހުންނަކީ، އެކަލާނގެ ނުކުޅައްދައި ރެކިގެންދާނޭ ބަޔަކު ކަމުގައި ނުވެތެވެ.","",""],["₁₀ سورة يونس","54","وَلَوۡ أَنَّ لِكُلِّ نَفۡسٖ ظَلَمَتۡ مَا فِي ٱلۡأَرۡضِ لَٱفۡتَدَتۡ بِهِۦۗ وَأَسَرُّواْ ٱلنَّدَامَةَ لَمَّا رَأَوُاْ ٱلۡعَذَابَۖ وَقُضِيَ بَيۡنَهُم بِٱلۡقِسۡطِ وَهُمۡ لَا يُظۡلَمُونَ ٥٤","ولو أن لكل نفس ظلمت ما في الأرض لافتدت به وأسروا الندامة لما رأوا العذاب وقضي بينهم بالقسط وهم لا يظلمون","އަނިޔާވެރި ކޮންމެ ނަފްސަކަށް، ބިމުގައިވާހާ ތަކެތި ލިބުނުނަމަ، (އަޒާބުން މިންޖުވުމަށް) އެތަކެތިން ފިދުޔަ ދިނީހެވެ. އަދި އެއުރެން އަޒާބު ދެކޭހިނދު، ހިތާމަވެރިކަން ހިތުތެރޭގައި އިޙުސާސްކުރާނެތެވެ. އަދި އެއުރެންގެ މެދުގައި ޢަދުލަށް ނިޔާކުރައްވާ ހުށްޓެވެ. އަދި އެއުރެންނަކަށް ބޭއިންސާފެއް ނުކުރައްވާ ހުށްޓެވެ.","",""],["₁₀ سورة يونس","55","أَلَآ إِنَّ لِلَّهِ مَا فِي ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِۗ أَلَآ إِنَّ وَعۡدَ ٱللَّهِ حَقّٞ وَلَٰكِنَّ أَكۡثَرَهُمۡ لَا يَعۡلَمُونَ ٥٥","ألا إن لله ما في السماوات والأرض ألا إن وعد الله حق ولكن أكثرهم لا يعلمون","ދަންނާށެވެ! ހަމަކަށަވަރުން، އުޑުތަކާއި، ބިމުގައިވާހާ ތަކެތި މަލަކަ ވެގެންވަނީ ﷲއަށެވެ. ދަންނާށެވެ! ހަމަކަށަވަރުން، ﷲގެ ވައުދު ފުޅަކީ ހައްގު ތެދެވެ. އެހެނެއްކަމަކު، އެއުރެންކުރެ ގިނަމީހުން (އެކަމެއް) ނުދަނެތެވެ.","",""],["₁₀ سورة يونس","56","هُوَ يُحۡيِۦ وَيُمِيتُ وَإِلَيۡهِ تُرۡجَعُونَ ٥٦","هو يحيي ويميت وإليه ترجعون","ދިރުއްވަނީވެސް، އަދި މަރުގަންނަވަނީވެސް އެކަލާނގެއެވެ. އަދި ތިޔަބައިމީހުން ރުޖޫއަކުރައްވާހުށީ، ހަމަ، އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["₁₀ سورة يونس","57","يَـٰٓأَيُّهَا ٱلنَّاسُ قَدۡ جَآءَتۡكُم مَّوۡعِظَةٞ مِّن رَّبِّكُمۡ وَشِفَآءٞ لِّمَا فِي ٱلصُّدُورِ وَهُدٗى وَرَحۡمَةٞ لِّلۡمُؤۡمِنِينَ ٥٧","يا أيها الناس قد جاءتكم موعظة من ربكم وشفاء لما في الصدور وهدى ورحمة للمؤمنين","އޭ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ތިޔަބައިމީހުންގެ ގާތަށް ވައުޒަކާއި، ހިތްތަކުގައިވާ ބަލިތަކަށް ޝިފާއަކާއި، މުއުމިނު ތަކުންނަށް ތެދުމަގަކާއި، ރަހުމަތެއް އަތުވެއްޖެކަން ކަށަވަރެވެ.","",""],["₁₀ سورة يونس","58","قُلۡ بِفَضۡلِ ٱللَّهِ وَبِرَحۡمَتِهِۦ فَبِذَٰلِكَ فَلۡيَفۡرَحُواْ هُوَ خَيۡرٞ مِّمَّا يَجۡمَعُونَ ٥٨","قل بفضل الله وبرحمته فبذلك فليفرحوا هو خير مما يجمعون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲގެ ފަޟްލުވަންތަ ކަމާއި، އެކަލާނގެ ރަހުމަތަށްޓަކައި (އެބަހީ: އިސްލާމް ދީނާއި ގުރްއާނަށްޓަކައި) ފަހެ، އެއުރެން އުފާކުރާހުށިކަމެވެ! އެއުރެން (ދުނިޔެމަތީގައި) އެއްކުރާ ތަކެއްޗަށްވުރެ، އެކަން ހެޔޮކަން ބޮޑެވެ.","",""],["₁₀ سورة يونس","59","قُلۡ أَرَءَيۡتُم مَّآ أَنزَلَ ٱللَّهُ لَكُم مِّن رِّزۡقٖ فَجَعَلۡتُم مِّنۡهُ حَرَامٗا وَحَلَٰلٗا قُلۡ ءَآللَّهُ أَذِنَ لَكُمۡۖ أَمۡ عَلَى ٱللَّهِ تَفۡتَرُونَ ٥٩","قل أرأيتم ما أنزل الله لكم من رزق فجعلتم منه حراما وحلالا قل آلله أذن لكم أم على الله تفترون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲ ތިޔަބައިމީހުންނަށް ބާވައިލެއްވި ރިޒްގާމެދު، ތިޔަބައިމީހުން ނިކަން ޚަބަރު ދީބަލާށެވެ! ފަހެ، ތިޔަބައިމީހުން އޭގެ ބައެއް ތަކެތި ހަރާމް ތަކެއްޗަށް އަނެއްބައި ތަކެތި ހަލާލު ތަކެއްޗަށް ހެދީމުއެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲ ތިޔަބައިމީހުންނަށް (އެކަމަށް) އިޒުނަ ދެއްވީހެއްޔެވެ؟ އަދި ކިއެއްތަ! ﷲއާމެދު ތިޔަބައިމީހުން ހަދައިގެން ދޮގެއް ބުނަނީއެވެ.","",""],["₁₀ سورة يونس","60","وَمَا ظَنُّ ٱلَّذِينَ يَفۡتَرُونَ عَلَى ٱللَّهِ ٱلۡكَذِبَ يَوۡمَ ٱلۡقِيَٰمَةِۗ إِنَّ ٱللَّهَ لَذُو فَضۡلٍ عَلَى ٱلنَّاسِ وَلَٰكِنَّ أَكۡثَرَهُمۡ لَا يَشۡكُرُونَ ٦٠","وما ظن الذين يفترون على الله الكذب يوم القيامة إن الله لذو فضل على الناس ولكن أكثرهم لا يشكرون","ﷲއާމެދު ހަދައިގެން ދޮގުބުނާ މީހުން، ގިޔާމަތް ދުވަހު، ހީކުރަނީ ކީކޭހެއްޔެވެ؟ ހަމަކަށަވަރުން، ﷲއީ، މީސްތަކުންގެ މައްޗަށް ފަޟްލު ވަންތަވެރި ރަސްކަލާނގެކަން ކަށަވަރެވެ. އެހެނެއްކަމަކު، އެއުރެންކުރެ ގިނަމީހުން ޝުކުރެއް ނުކުރެތެވެ.","",""],["₁₀ سورة يونس","61","وَمَا تَكُونُ فِي شَأۡنٖ وَمَا تَتۡلُواْ مِنۡهُ مِن قُرۡءَانٖ وَلَا تَعۡمَلُونَ مِنۡ عَمَلٍ إِلَّا كُنَّا عَلَيۡكُمۡ شُهُودًا إِذۡ تُفِيضُونَ فِيهِۚ وَمَا يَعۡزُبُ عَن رَّبِّكَ مِن مِّثۡقَالِ ذَرَّةٖ فِي ٱلۡأَرۡضِ وَلَا فِي ٱلسَّمَآءِ وَلَآ أَصۡغَرَ مِن ذَٰلِكَ وَلَآ أَكۡبَرَ إِلَّا فِي كِتَٰبٖ مُّبِينٍ ٦١","وما تكون في شأن وما تتلو منه من قرآن ولا تعملون من عمل إلا كنا عليكم شهودا إذ تفيضون فيه وما يعزب عن ربك من مثقال ذرة في الأرض ولا في السماء ولا أصغر من ذلك ولا أكبر إلا في كتاب مبين","ކަލޭގެފާނު ކޮންމެ ކަމެއްގައި އުޅުއްވިޔަސް، އަދި ކަލޭގެފާނު ގުރްއާނުން ކޮންމެ އެއްޗެއް ކިޔަވައިވިދާޅުވިޔަސް، އަދި ތިޔަބައިމީހުން ކޮންމެ ޢަމަލެއް ކުރިޔަސް، އެ ޢަމަލުގެ ތެރޭގައި ތިޔަބައިމީހުން އުޅޭހިނދު، ތިޔަބައިމީހުންގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ހެކިވެވޮޑިގެންވާ ކަމުގައި މެނުވީ ނުވަމެވެ. އަދި އުޑާއި، ބިމުގައިވާ ޒައްރެއްގެ މިންވަރުވެސް، އަދި އެއަށްވުރެ ކުޑަޔަސް، އަދި އެއަށްވުރެ ބޮޑަސް، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް ވަންހަނާވެގެނެއްނުވެތެވެ. ބަޔާންވެގެންވާ ފޮތެއްގައި އެތަކެތި ލިޔުއްވާފައިމެނުވީ ނުވެތެވެ.","",""],["₁₀ سورة يونس","62","أَلَآ إِنَّ أَوۡلِيَآءَ ٱللَّهِ لَا خَوۡفٌ عَلَيۡهِمۡ وَلَا هُمۡ يَحۡزَنُونَ ٦٢","ألا إن أولياء الله لا خوف عليهم ولا هم يحزنون","ދަންނާށެވެ! ހަމަކަށަވަރުން، ﷲގެ ވަލިއްޔުންގެ މައްޗަކަށް އެއްވެސް ބިރެއްނެތެވެ. އަދި އެއުރެންނީ ހިތާމަކުރާނޭ ބަޔަކު ކަމުގައިވެސް ނުމެވޭމެއެވެ.","",""],["₁₀ سورة يونس","63","ٱلَّذِينَ ءَامَنُواْ وَكَانُواْ يَتَّقُونَ ٦٣","الذين آمنوا وكانوا يتقون","އެއުރެންނަކީ އީމާންވެ، ތަގުވާވެރިވެ އުޅުނު މީހުންނެވެ.","",""],["₁₀ سورة يونس","64","لَهُمُ ٱلۡبُشۡرَىٰ فِي ٱلۡحَيَوٰةِ ٱلدُّنۡيَا وَفِي ٱلۡأٓخِرَةِۚ لَا تَبۡدِيلَ لِكَلِمَٰتِ ٱللَّهِۚ ذَٰلِكَ هُوَ ٱلۡفَوۡزُ ٱلۡعَظِيمُ ٦٤","لهم البشرى في الحياة الدنيا وفي الآخرة لا تبديل لكلمات الله ذلك هو الفوز العظيم","ދުނިޔޭގެ ހަޔާތް ގައްޔާއި، އާޚިރަތުގައި އެއުރެންނަށް އުފާވެރިކަމުގެ ޚަބަރު ހުށްޓެވެ. ﷲގެ ކަލިމަ ފުޅުތަކަށް ބަދަލުވުމެއް ނާންނަހުށްޓެވެ. ބޮޑުވެގެންވާ ނަސީބު ލިބުމަކީ ހަމަ އެއީއެވެ.","",""],["₁₀ سورة يونس","65","وَلَا يَحۡزُنكَ قَوۡلُهُمۡۘ إِنَّ ٱلۡعِزَّةَ لِلَّهِ جَمِيعًاۚ هُوَ ٱلسَّمِيعُ ٱلۡعَلِيمُ ٦٥","ولا يحزنك قولهم إن العزة لله جميعا هو السميع العليم","އެއުރެންގެ (ދޮގު) ވާހަކަތައް ކަލޭގެފާނު ހިތާމަވެރިކުރުވިޔަ ނުދެއްވާށެވެ! ހަމަކަށަވަރުން، ހުރިހާ ޢިއްޒަތެއް މަލަކަ ވެގެންވަނީ ﷲއަށެވެ. އެކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₁₀ سورة يونس","66","أَلَآ إِنَّ لِلَّهِ مَن فِي ٱلسَّمَٰوَٰتِ وَمَن فِي ٱلۡأَرۡضِۗ وَمَا يَتَّبِعُ ٱلَّذِينَ يَدۡعُونَ مِن دُونِ ٱللَّهِ شُرَكَآءَۚ إِن يَتَّبِعُونَ إِلَّا ٱلظَّنَّ وَإِنۡ هُمۡ إِلَّا يَخۡرُصُونَ ٦٦","ألا إن لله من في السماوات ومن في الأرض وما يتبع الذين يدعون من دون الله شركاء إن يتبعون إلا الظن وإن هم إلا يخرصون","ދަންނާށެވެ! ހަމަކަށަވަރުން، އުޑުތަކުގައިވާހާ ބަޔަކާއި، ބިމުގައިވާހާ ބަޔެއް މަލަކަ ވެގެންވަނީ، ﷲއަށެވެ. ﷲ ނޫންފަރާތަކަށް، އަޅުކަންކުރާ މީހުން (ހަގީގަތުގައި) ޝަރީކުންނަކާ ތަބައެއް ނުވެތެވެ. އެއުރެން އެ ތަބާ ވަނީ، ހީއަކަށް ކަމުގައިނޫނީ ނުވެތެވެ. އަދި ދޮގުހަދާ ބަޔަކު ކަމުގައި ނޫނީ އެއުރެން ނުވެތެވެ.","",""],["₁₀ سورة يونس","67","هُوَ ٱلَّذِي جَعَلَ لَكُمُ ٱلَّيۡلَ لِتَسۡكُنُواْ فِيهِ وَٱلنَّهَارَ مُبۡصِرًاۚ إِنَّ فِي ذَٰلِكَ لَأٓيَٰتٖ لِّقَوۡمٖ يَسۡمَعُونَ ٦٧","هو الذي جعل لكم الليل لتسكنوا فيه والنهار مبصرا إن في ذلك لآيات لقوم يسمعون","އެކަލާނގެއީ، ތިޔަބައިމީހުން (އަރާމުކޮށް) ހަމަހިމޭންވުމަށް ތިޔަބައިމީހުންނަށްޓަކައި، ރޭގަނޑު ލެއްވި ރަސްކަލާނގެއެވެ. އަދި (ތިޔަބައިމީހުން ދިރިއުޅުމުގެ މަސައްކަތް ކުރުމަށް) ދުވާލު އަލިކޮށްދެއްވި ރަސްކަލާނގެއެވެ. ހަމަކަށަވަރުން، އެކަންތައްތަކުގައި، އަޑުއަހާ ބަޔަކަށް ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["₁₀ سورة يونس","68","قَالُواْ ٱتَّخَذَ ٱللَّهُ وَلَدٗاۗ سُبۡحَٰنَهُۥۖ هُوَ ٱلۡغَنِيُّۖ لَهُۥ مَا فِي ٱلسَّمَٰوَٰتِ وَمَا فِي ٱلۡأَرۡضِۚ إِنۡ عِندَكُم مِّن سُلۡطَٰنِۭ بِهَٰذَآۚ أَتَقُولُونَ عَلَى ٱللَّهِ مَا لَا تَعۡلَمُونَ ٦٨","قالوا اتخذ الله ولدا سبحانه هو الغني له ما في السماوات وما في الأرض إن عندكم من سلطان بهذا أتقولون على الله ما لا تعلمون","ﷲ ދަރިކަލަކު ހިއްޕެވިކަމަށް އެއުރެން ބުނެފޫއެވެ. އެކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! އެކަލާނގެއީ، ފުދިވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އުޑުތަކުގައިވާހާ ތަކެއްޗާއި ބިމުގައިވާހާ ތަކެތި މަލަކަ ވެގެންވަނީ އެކަލާނގެއަށެވެ. ތިޔަބައިމީހުން ތިޔަބުނާ ބަހުގެ މައްޗަށް ތިޔަބައިމީހުންގެ ގާތުގައި އެއްވެސް ދަލީލެއް ނެތެވެ. ތިޔަބައިމީހުންނަށް، އެނގިގެންނުވާ އެއްޗެއް ﷲއާމެދު ތިޔަބައިމީހުން ބުނަނީހެއްޔެވެ؟","",""],["₁₀ سورة يونس","69","قُلۡ إِنَّ ٱلَّذِينَ يَفۡتَرُونَ عَلَى ٱللَّهِ ٱلۡكَذِبَ لَا يُفۡلِحُونَ ٦٩","قل إن الذين يفترون على الله الكذب لا يفلحون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ﷲއާމެދު ހަދައިގެން ދޮގުބުނާ މީހުން ނުދިނޭނެތެވެ.","",""],["₁₀ سورة يونس","70","مَتَٰعٞ فِي ٱلدُّنۡيَا ثُمَّ إِلَيۡنَا مَرۡجِعُهُمۡ ثُمَّ نُذِيقُهُمُ ٱلۡعَذَابَ ٱلشَّدِيدَ بِمَا كَانُواْ يَكۡفُرُونَ ٧٠","متاع في الدنيا ثم إلينا مرجعهم ثم نذيقهم العذاب الشديد بما كانوا يكفرون","ދުނިޔޭގައި (ލިބޭ) ވަގުތީ އުފަލެކެވެ. ދެން އެއުރެން ރުޖޫއަ ވުން ވަނީ، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށެވެ. ދެން އެއުރެން ކާފިރުވެ އުޅުނުކަމުގެ ސަބަބުން، ގަދަފަދަވެގެންވާ އަޒާބުގެ ރަހަ، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދައްކަވާހުށީމެވެ.","",""],["₁₀ سورة يونس","71","۞وَٱتۡلُ عَلَيۡهِمۡ نَبَأَ نُوحٍ إِذۡ قَالَ لِقَوۡمِهِۦ يَٰقَوۡمِ إِن كَانَ كَبُرَ عَلَيۡكُم مَّقَامِي وَتَذۡكِيرِي بِـَٔايَٰتِ ٱللَّهِ فَعَلَى ٱللَّهِ تَوَكَّلۡتُ فَأَجۡمِعُوٓاْ أَمۡرَكُمۡ وَشُرَكَآءَكُمۡ ثُمَّ لَا يَكُنۡ أَمۡرُكُمۡ عَلَيۡكُمۡ غُمَّةٗ ثُمَّ ٱقۡضُوٓاْ إِلَيَّ وَلَا تُنظِرُونِ ٧١","واتل عليهم نبأ نوح إذ قال لقومه يا قوم إن كان كبر عليكم مقامي وتذكيري بآيات الله فعلى الله توكلت فأجمعوا أمركم وشركاءكم ثم لا يكن أمركم عليكم غمة ثم اقضوا إلي ولا تنظرون","ނޫޙުގެފާނުގެ ވާހަކަ އެއުރެންނަށް ކަލޭގެފާނު ކިޔައިދެއްވާށެވެ! އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް ވިދާޅުވި ހިނދުގައެވެ. އޭ ތިމަންކަލޭގެފާނުގެ ގައުމުގެމީހުންނޭވެ! ތިމަންކަލޭގެފާނު ތިޔަބައިމީހުންގެ ތެރޭގައި ހުންނެވުމާއި، ﷲގެ އާޔަތް ތަކުން ތިމަންކަލޭގެފާނު ތިޔަބައިމީހުންނަށް ހަނދާންކޮށް ދެއްވުން، ތިޔަބައިމީހުންގެ މައްޗަށް ބޮޑުކަމަކަށް ވެއްޖެނަމަ، ފަހެ، ތިމަންކަލޭގެފާނު، ﷲއަށް ވަކީލުކުރައްވައިފީމެވެ. ދެން ތިޔަބައިމީހުންގެ ބައިވެރިންނާއެކު، ތިޔަބައިމީހުންގެ ކަންތަކާމެދު އެއްބަސްވާށެވެ! ދެން ތިޔަބައިމީހުންގެ ކަންތައް (ނިންމިގޮތް) ތިޔަބައިމީހުންނަށް އޮޅޭގޮތެއްގައި، ވަންހަނާވެފައި އޮވެގެނެއް ނުވާނެއެވެ. ދެން ތިޔަބައިމީހުން ނިންމިގޮތް، ތިމަންކަލޭގެފާނުގެ މައްޗަށް ހިންގާށެވެ! އަދި ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނަށް މުހުލަތް ނުދޭށެވެ!","",""],["₁₀ سورة يونس","72","فَإِن تَوَلَّيۡتُمۡ فَمَا سَأَلۡتُكُم مِّنۡ أَجۡرٍۖ إِنۡ أَجۡرِيَ إِلَّا عَلَى ٱللَّهِۖ وَأُمِرۡتُ أَنۡ أَكُونَ مِنَ ٱلۡمُسۡلِمِينَ ٧٢","فإن توليتم فما سألتكم من أجر إن أجري إلا على الله وأمرت أن أكون من المسلمين","ފަހެ، ތިޔަބައިމީހުން ފުރަގަސްދީފިނަމަ (ދަންނާށެވެ!) ފަހެ، ތިޔަބައިމީހުންގެ ކިބަޔަކުން އުޖޫރައަކަށް ތިމަންކަލޭގެފާނު އެދިވަޑައެއް ނުގަންނަވަމެވެ. ތިމަންކަލޭގެފާނުގެ އުޖޫރަ، ﷲގެ ހަޒުރަތުގައި މެނުވީ ނުވެތެވެ. އަދި ތިމަންކަލޭގެފާނަށް އަމުރުކުރައްވާފައިވަނީ، ތިމަންކަލޭގެފާނު މުސްލިމުންގެ ތެރެއިން ވުމަށެވެ.","",""],["₁₀ سورة يونس","73","فَكَذَّبُوهُ فَنَجَّيۡنَٰهُ وَمَن مَّعَهُۥ فِي ٱلۡفُلۡكِ وَجَعَلۡنَٰهُمۡ خَلَـٰٓئِفَ وَأَغۡرَقۡنَا ٱلَّذِينَ كَذَّبُواْ بِـَٔايَٰتِنَاۖ فَٱنظُرۡ كَيۡفَ كَانَ عَٰقِبَةُ ٱلۡمُنذَرِينَ ٧٣","فكذبوه فنجيناه ومن معه في الفلك وجعلناهم خلائف وأغرقنا الذين كذبوا بآياتنا فانظر كيف كان عاقبة المنذرين","ފަހެ، އެއުރެން އެކަލޭގެފާނު ދޮގުކުރޫއެވެ. ދެން ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނާއި، އެކަލޭގެފާނުގެ އަރިހުގައި ނާކޮޅުގައިވާ އެންމެން ސަލާމަތް ކުރެއްވީމެވެ. އަދި އޭގެފަހުން (ބިމުގައި) އުޅޭނެ ބަޔަކު ކަމުގައި އެއުރެން ލެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުރިމީހުން ޣަރަގުކުރެއްވީމެވެ. ފަހެ، އިންޒާރު ވެވުނު މީހުންގެ ނިމުންހުރީ، ކޮންފަދައަކުންކަން ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާށެވެ!","",""],["₁₀ سورة يونس","74","ثُمَّ بَعَثۡنَا مِنۢ بَعۡدِهِۦ رُسُلًا إِلَىٰ قَوۡمِهِمۡ فَجَآءُوهُم بِٱلۡبَيِّنَٰتِ فَمَا كَانُواْ لِيُؤۡمِنُواْ بِمَا كَذَّبُواْ بِهِۦ مِن قَبۡلُۚ كَذَٰلِكَ نَطۡبَعُ عَلَىٰ قُلُوبِ ٱلۡمُعۡتَدِينَ ٧٤","ثم بعثنا من بعده رسلا إلى قومهم فجاءوهم بالبينات فما كانوا ليؤمنوا بما كذبوا به من قبل كذلك نطبع على قلوب المعتدين","ދެން އެކަލޭގެފާނަށް ފަހުގައި ތިމަންރަސްކަލާނގެ ރަސޫލުންތަކެއް އެބޭކަލުންގެ ގައުމުގެމީހުންގެ ގާތަށް ފޮނުއްވީމެވެ. ފަހެ، ބަޔާން ވެގެންވާ ހެކިތައް އެއުރެންނަށް އެބޭކަލުން ގެނެސްދެއްވޫއެވެ. (ނަމަވެސް) ކުރިން އެއުރެން ދޮގުކުރި ކަންތަކަށް އީމާންވާ ބަޔަކު ކަމުގައި އެއުރެން ނުވިއެވެ. ހަމައެފަދައިން ދެކޮޅުވެރިވެ ހައްދުފަހަނަޅައިދާ މީހުންގެ ހިތްތަކުގައި ތިމަންރަސްކަލާނގެ ސިއްކަގައްސަވާހުށީމެވެ.","",""],["₁₀ سورة يونس","75","ثُمَّ بَعَثۡنَا مِنۢ بَعۡدِهِم مُّوسَىٰ وَهَٰرُونَ إِلَىٰ فِرۡعَوۡنَ وَمَلَإِيْهِۦ بِـَٔايَٰتِنَا فَٱسۡتَكۡبَرُواْ وَكَانُواْ قَوۡمٗا مُّجۡرِمِينَ ٧٥","ثم بعثنا من بعدهم موسى وهارون إلى فرعون وملئه بآياتنا فاستكبروا وكانوا قوما مجرمين","ދެން އެބޭކަލުންނަށް ފަހުގައި، ފިރްޢައުނާއި، އޭނާގެ ބޮޑުންގެ ގާތަށް، ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާއިގެން މޫސާގެފާނާއި، ހާރޫނުގެފާނު ފޮނުއްވީމެވެ. ދެން އެއުރެން ކިބުރުވެރިވެގަތޫއެވެ. އަދި ކުށްވެރި ބަޔަކު ކަމުގައި އެއުރެންވިއެވެ.","",""],["₁₀ سورة يونس","76","فَلَمَّا جَآءَهُمُ ٱلۡحَقُّ مِنۡ عِندِنَا قَالُوٓاْ إِنَّ هَٰذَا لَسِحۡرٞ مُّبِينٞ ٧٦","فلما جاءهم الحق من عندنا قالوا إن هذا لسحر مبين","ފަހެ، ތިމަންރަސްކަލާނގެ ހަޒުރަތުން އެއުރެންގެ ގާތަށް ހައްގު އައުމުން، އެއުރެން ބުނެފޫއެވެ. ހަމަކަށަވަރުން، މިއީ ބަޔާންވެގެންވާ ޖާދޫއެއްކަން ކަށަވަރެވެ.","",""],["₁₀ سورة يونس","77","قَالَ مُوسَىٰٓ أَتَقُولُونَ لِلۡحَقِّ لَمَّا جَآءَكُمۡۖ أَسِحۡرٌ هَٰذَا وَلَا يُفۡلِحُ ٱلسَّـٰحِرُونَ ٧٧","قال موسى أتقولون للحق لما جاءكم أسحر هذا ولا يفلح الساحرون","މޫސާގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންގެ ގާތަށް ހައްގު އައިހިނދު، އެ ހައްގަށް މިއީ ޖާދޫއެއްހޭ ތިޔަބައިމީހުން ބުނަނީހެއްޔެވެ؟ އަދި ޖާދޫހަދާ މީހުން ނުދިނޭހުށްޓެވެ.","",""],["₁₀ سورة يونس","78","قَالُوٓاْ أَجِئۡتَنَا لِتَلۡفِتَنَا عَمَّا وَجَدۡنَا عَلَيۡهِ ءَابَآءَنَا وَتَكُونَ لَكُمَا ٱلۡكِبۡرِيَآءُ فِي ٱلۡأَرۡضِ وَمَا نَحۡنُ لَكُمَا بِمُؤۡمِنِينَ ٧٨","قالوا أجئتنا لتلفتنا عما وجدنا عليه آباءنا وتكون لكما الكبرياء في الأرض وما نحن لكما بمؤمنين","އެއުރެން ދެންނެވޫއެވެ. ކަލޭގެފާނު ތިޔަވަޑައިގަތީ، ތިމަންމެންގެ ކާބަފައިން އުޅޭތީ ތިމަންމެންނަށް ފެނުނުގޮތުން ތިމަންމެން އެއްކިބާކުރައްވައި ތިޔަ ދެބޭކަލުންނަށް ބިމުގައި ވެރިކަން ހޯއްދެވުމަށްތޯއެވެ؟ ތިޔަ ދެބޭކަލުންނަށް އީމާންވާ ބަޔަކު ކަމުގައި ތިމަންމެން ނުވަމުއެވެ.","",""],["₁₀ سورة يونس","79","وَقَالَ فِرۡعَوۡنُ ٱئۡتُونِي بِكُلِّ سَٰحِرٍ عَلِيمٖ ٧٩","وقال فرعون ائتوني بكل ساحر عليم","ފިރްޢައުނު ބުންޏެވެ. މޮޅަށް ދަންނަ ހުރިހާ ޖާދޫގަރުން ތިމަންގެ ގާތަށް ގެނެސްދޭށެވެ!","",""],["₁₀ سورة يونس","80","فَلَمَّا جَآءَ ٱلسَّحَرَةُ قَالَ لَهُم مُّوسَىٰٓ أَلۡقُواْ مَآ أَنتُم مُّلۡقُونَ ٨٠","فلما جاء السحرة قال لهم موسى ألقوا ما أنتم ملقون","ފަހެ، އެ ޖާދޫގަރުން އައިހިނދު އެއުރެންނަށް މޫސާގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން (ޖާދޫގެގޮތުން) އުކަންހުރި ތަކެތި އުކާށެވެ!","",""],["₁₀ سورة يونس","81","فَلَمَّآ أَلۡقَوۡاْ قَالَ مُوسَىٰ مَا جِئۡتُم بِهِ ٱلسِّحۡرُۖ إِنَّ ٱللَّهَ سَيُبۡطِلُهُۥٓ إِنَّ ٱللَّهَ لَا يُصۡلِحُ عَمَلَ ٱلۡمُفۡسِدِينَ ٨١","فلما ألقوا قال موسى ما جئتم به السحر إن الله سيبطله إن الله لا يصلح عمل المفسدين","ފަހެ، އެއުރެން (އެތަކެތި) އުކިހިނދު، މޫސާގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން ތިޔަ ގެނައީ ޖާދޫއެވެ. ހަމަކަށަވަރުން، ﷲ، އެ ޖާދޫ ބާތިލުކުރައްވާނެތެވެ. ހަމަކަށަވަރުން، ފަސާދަކުރާ މީހުންގެ ޢަމަލު، ﷲ އިޞްލާޙެއް ނުކުރައްވާހުށްޓެވެ.","",""],["₁₀ سورة يونس","82","وَيُحِقُّ ٱللَّهُ ٱلۡحَقَّ بِكَلِمَٰتِهِۦ وَلَوۡ كَرِهَ ٱلۡمُجۡرِمُونَ ٨٢","ويحق الله الحق بكلماته ولو كره المجرمون","އަދި ކުށްވެރިން ނުރުހުނަސް، ﷲ އެކަލާނގެ ކަލިމަ ފުޅުތަކުން ހައްގު ސާބިތުކުރައްވައި ފާޅުކުރައްވާނެތެވެ.","",""],["₁₀ سورة يونس","83","فَمَآ ءَامَنَ لِمُوسَىٰٓ إِلَّا ذُرِّيَّةٞ مِّن قَوۡمِهِۦ عَلَىٰ خَوۡفٖ مِّن فِرۡعَوۡنَ وَمَلَإِيْهِمۡ أَن يَفۡتِنَهُمۡۚ وَإِنَّ فِرۡعَوۡنَ لَعَالٖ فِي ٱلۡأَرۡضِ وَإِنَّهُۥ لَمِنَ ٱلۡمُسۡرِفِينَ ٨٣","فما آمن لموسى إلا ذرية من قومه على خوف من فرعون وملئهم أن يفتنهم وإن فرعون لعال في الأرض وإنه لمن المسرفين","ފަހެ، މޫސާގެފާނަށް އެކަލޭގެފާނުގެ ގައުމުގެ ބައެއް ދަރިކޮޅު މެނުވީ އީމާނެއް ނުވެތެވެ. (އެއީ) ފިރްޢައުނާއި، އޭނާގެ ބޮޑުންނަށް ބިރުންނެވެ. އެއުރެންނަށް އަނިޔާކޮށް، ދީނުން އެއްކިބާކޮށްފާނެ ކަމަށްޓަކައެވެ. އަދި ހަމަކަށަވަރުން، ފިރްޢައުނަކީ، ބިމުގައި ވަރަށް ބޮޑާވެގެން އުޅުނު މީހެކެވެ. އަދި ހަމަކަށަވަރުން، އޭނާވަނީ (އަނިޔާވެރިކަމާއި ފަސާދަވެރިކަމުގައި) ހައްދުފަހަނަޅައިފައިވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["₁₀ سورة يونس","84","وَقَالَ مُوسَىٰ يَٰقَوۡمِ إِن كُنتُمۡ ءَامَنتُم بِٱللَّهِ فَعَلَيۡهِ تَوَكَّلُوٓاْ إِن كُنتُم مُّسۡلِمِينَ ٨٤","وقال موسى يا قوم إن كنتم آمنتم بالله فعليه توكلوا إن كنتم مسلمين","އަދި މޫސާގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނެވެ! ތިޔަބައިމީހުން ﷲއަށް އީމާން ވެގެންވާނަމަ، ފަހެ، އެކަލާނގެއަށް ވަކީލުކުރާށެވެ! ތިޔަބައިމީހުންނީ މުސްލިމުން ކަމުގައި ވާނަމައެވެ.","",""],["₁₀ سورة يونس","85","فَقَالُواْ عَلَى ٱللَّهِ تَوَكَّلۡنَا رَبَّنَا لَا تَجۡعَلۡنَا فِتۡنَةٗ لِّلۡقَوۡمِ ٱلظَّـٰلِمِينَ ٨٥","فقالوا على الله توكلنا ربنا لا تجعلنا فتنة للقوم الظالمين","ފަހެ، އެއުރެން ދެންނެވޫއެވެ. ﷲއަށް އަޅަމެން ވަކީލު ކޮށްފީމެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! އަނިޔާވެރިވީ މީހުންނަށް ފިތުނައެއްކަމުގައި (އެބަހީ: އެއުރެންގެ އަނިޔާވެރިކަމުގެ ދަށުގައި) އަޅަމެން ނުލައްވާނދޭވެ!","",""],["₁₀ سورة يونس","86","وَنَجِّنَا بِرَحۡمَتِكَ مِنَ ٱلۡقَوۡمِ ٱلۡكَٰفِرِينَ ٨٦","ونجنا برحمتك من القوم الكافرين","އަދި ކާފިރުވި މީހުންގެ ކިބައިން، އިބަރަސްކަލާނގެ ރަހުމަތް ފުޅާލައިގެން އަޅަމެން ސަލާމަތް ކުރައްވާނދޭވެ!","",""],["₁₀ سورة يونس","87","وَأَوۡحَيۡنَآ إِلَىٰ مُوسَىٰ وَأَخِيهِ أَن تَبَوَّءَا لِقَوۡمِكُمَا بِمِصۡرَ بُيُوتٗا وَٱجۡعَلُواْ بُيُوتَكُمۡ قِبۡلَةٗ وَأَقِيمُواْ ٱلصَّلَوٰةَۗ وَبَشِّرِ ٱلۡمُؤۡمِنِينَ ٨٧","وأوحينا إلى موسى وأخيه أن تبوآ لقومكما بمصر بيوتا واجعلوا بيوتكم قبلة وأقيموا الصلاة وبشر المؤمنين","ތިމަންރަސްކަލާނގެ މޫސާގެފާނާއި، އެކަލޭގެފާނުގެ އަޚު (ހާރޫނުގެފާނު) އަށް ވަހީކުރެއްވީމެވެ. ތިޔަ ދެބޭކަލުންގެ ގައުމުގެމީހުންނަށް މިސްރުގައި ގޭގެ ހައްދަވާށެވެ! އަދި ތިޔަބައިމީހުންގެ ގޭގެ، ގިބްލަށް ބަހައްޓައި، ނަމާދު ގާއިމުކުރާށެވެ! އަދި ކަލޭގެފާނު މުއުމިނު ތަކުންނަށް (ނަސްރު ލިބޭނެކަމުގެ) އުފާވެރި ޚަބަރު ދެއްވާށެވެ!","",""],["₁₀ سورة يونس","88","وَقَالَ مُوسَىٰ رَبَّنَآ إِنَّكَ ءَاتَيۡتَ فِرۡعَوۡنَ وَمَلَأَهُۥ زِينَةٗ وَأَمۡوَٰلٗا فِي ٱلۡحَيَوٰةِ ٱلدُّنۡيَا رَبَّنَا لِيُضِلُّواْ عَن سَبِيلِكَۖ رَبَّنَا ٱطۡمِسۡ عَلَىٰٓ أَمۡوَٰلِهِمۡ وَٱشۡدُدۡ عَلَىٰ قُلُوبِهِمۡ فَلَا يُؤۡمِنُواْ حَتَّىٰ يَرَوُاْ ٱلۡعَذَابَ ٱلۡأَلِيمَ ٨٨","وقال موسى ربنا إنك آتيت فرعون وملأه زينة وأموالا في الحياة الدنيا ربنا ليضلوا عن سبيلك ربنا اطمس على أموالهم واشدد على قلوبهم فلا يؤمنوا حتى يروا العذاب الأليم","މޫސާގެފާނު ދެންނެވިއެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެ ފިރްޢައުނަށާއި، އޭނާގެ ބޮޑުންނަށް ދުނިޔޭގެ ދިރިއުޅުމުގައި ޒީނަތްތެރިކަމާއި، މުދާތައް ދެއްވީމުއެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! (އެތަކެތިން) އެއުރެން އިބަރަސްކަލާނގެ ތެދުމަގުން (މީސްތަކުން) އެއްކިބާކުރެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! އެއުރެންގެ މުދާތައް ހަލާކު ކުރައްވައި، ނެތިކުރައްވާނދޭވެ! އަދި އެއުރެންގެ ހިތްތައް ހަރުކަށިކުރައްވައި، ސިއްކަގައްސަވާނދޭވެ! ފަހެ، އެއުރެންނަށް ވޭންދެނިވި އަޒާބު ފެނިއްޖައުމަށް ދާނދެން، އެއުރެން އީމާނެއް ނުވާނެތެވެ.","",""],["₁₀ سورة يونس","89","قَالَ قَدۡ أُجِيبَت دَّعۡوَتُكُمَا فَٱسۡتَقِيمَا وَلَا تَتَّبِعَآنِّ سَبِيلَ ٱلَّذِينَ لَا يَعۡلَمُونَ ٨٩","قال قد أجيبت دعوتكما فاستقيما ولا تتبعان سبيل الذين لا يعلمون","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ހަމަކަށަވަރުން، ތިޔަ ދެބޭކަލުންގެ ދުއާ އިޖާބަކުރައްވައިފީމެވެ. ފަހެ، ތިޔަ ދެބޭކަލުން ސީދާގޮތުގައި ތިއްބަވާށެވެ! ނުދަންނަ މީހުންގެ މަގަށް ތިޔަ ދެބޭކަލުން ތަބާ ވެވަޑައި ނުގަންނަވާހުށިކަމެވެ!","",""],["₁₀ سورة يونس","90","۞وَجَٰوَزۡنَا بِبَنِيٓ إِسۡرَـٰٓءِيلَ ٱلۡبَحۡرَ فَأَتۡبَعَهُمۡ فِرۡعَوۡنُ وَجُنُودُهُۥ بَغۡيٗا وَعَدۡوًاۖ حَتَّىٰٓ إِذَآ أَدۡرَكَهُ ٱلۡغَرَقُ قَالَ ءَامَنتُ أَنَّهُۥ لَآ إِلَٰهَ إِلَّا ٱلَّذِيٓ ءَامَنَتۡ بِهِۦ بَنُوٓاْ إِسۡرَـٰٓءِيلَ وَأَنَا۠ مِنَ ٱلۡمُسۡلِمِينَ ٩٠","وجاوزنا ببني إسرائيل البحر فأتبعهم فرعون وجنوده بغيا وعدوا حتى إذا أدركه الغرق قال آمنت أنه لا إله إلا الذي آمنت به بنو إسرائيل وأنا من المسلمين","ކަނޑުހުރަސް ކުރައްވައި، ތިމަންރަސްކަލާނގެ އިސްރާއީލުގެދަރިން ގެންދެވީމެވެ. ފަހެ، ފިރްޢައުނާއި، އޭނާގެ ލަޝްކަރު ދެކޮޅުވެރިކަމާއި، އަދާވަތް ތެރިކަމުގެ ގޮތުގައި އެއުރެންގެ ފަހަތުން ދިޔައޫއެވެ. ދެން އެ ފިރްޢައުނު، ޣަރަގު ވީހިނދު އޭނާ ބުންޏެވެ. އިސްރާއީލުގެދަރިން އީމާން ވީ ކަލާނގެ މެނުވީ، އެހެންކަލަކު ނެތްކަމަށް އަހުރެން އީމާން ވެއްޖައީމެވެ. އަދި އަހުރެން ވަނީ މުސްލިމުންގެ ތެރެއިންނެވެ.","",""],["₁₀ سورة يونس","91","ءَآلۡـَٰٔنَ وَقَدۡ عَصَيۡتَ قَبۡلُ وَكُنتَ مِنَ ٱلۡمُفۡسِدِينَ ٩١","آلآن وقد عصيت قبل وكنت من المفسدين","(އެވަގުތު ފިރްޢައުނަށް އެންގެވިއެވެ. ކަލޭ ތިޔަ އީމާން ވީ) މިހާރު ހެއްޔެވެ؟ ކަލޭ މީގެކުރިންވަނީ އުރެދިފައެވެ. އަދި ކަލޭވީ، ފަސާދަކުރާ މީހުންގެ ތެރެއިންނެވެ.","",""],["₁₀ سورة يونس","92","فَٱلۡيَوۡمَ نُنَجِّيكَ بِبَدَنِكَ لِتَكُونَ لِمَنۡ خَلۡفَكَ ءَايَةٗۚ وَإِنَّ كَثِيرٗا مِّنَ ٱلنَّاسِ عَنۡ ءَايَٰتِنَا لَغَٰفِلُونَ ٩٢","فاليوم ننجيك ببدنك لتكون لمن خلفك آية وإن كثيرا من الناس عن آياتنا لغافلون","ފަހެ، ތިމަންރަސްކަލާނގެ، މިއަދު ކަލޭގެ (ފުރާނަނެތް) ހަށިގަނޑު ސަލާމަތްކުރައްވާހުށީމެވެ. އެއީ، ކަލޭގެފަހުން އަންނަބަޔަކަށް، އިބްރަތެއް ކަމުގައި ކަލޭ ވުމަށެވެ. ހަމަކަށަވަރުން، މީސްތަކުންގެ ތެރެއިން ގިނަމީހުންވަނީ ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާމެދު (އެބަހީ: ތިމަންރަސްކަލާނގެ ގުދުރަތް ތެރިކަމުގެ މައްޗަށް ދަލީލުކުރާ ހެކިތަކާމެދު) ޣާފިލު ވެގެންކަން ކަށަވަރެވެ.","",""],["₁₀ سورة يونس","93","وَلَقَدۡ بَوَّأۡنَا بَنِيٓ إِسۡرَـٰٓءِيلَ مُبَوَّأَ صِدۡقٖ وَرَزَقۡنَٰهُم مِّنَ ٱلطَّيِّبَٰتِ فَمَا ٱخۡتَلَفُواْ حَتَّىٰ جَآءَهُمُ ٱلۡعِلۡمُۚ إِنَّ رَبَّكَ يَقۡضِي بَيۡنَهُمۡ يَوۡمَ ٱلۡقِيَٰمَةِ فِيمَا كَانُواْ فِيهِ يَخۡتَلِفُونَ ٩٣","ولقد بوأنا بني إسرائيل مبوأ صدق ورزقناهم من الطيبات فما اختلفوا حتى جاءهم العلم إن ربك يقضي بينهم يوم القيامة فيما كانوا فيه يختلفون","ހަމަކަށަވަރުން، އިސްރާއީލުގެދަރިންނަށް ރަނގަޅު މޮޅު މަންޒިލެއް (އެބަހީ: މިޞްރާއި ޝާމް) ތިމަންރަސްކަލާނގެ ދެއްކެވީމެވެ. އަދި ރަނގަޅު ތަކެތިން، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ރިޒްގު ދެއްވީމެވެ. ދެން އެއުރެންނާ ހަމަޔަށް އިލްމު އަތުވެއްޖެއުމަށް ދާނދެން، އެއުރެން ޚިލާފެއް ނުވެތެވެ. ހަމަކަށަވަރުން، އެއުރެން ޚިލާފުވެ އުޅުނު ކަންތަކާމެދު، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ގިޔާމަތް ދުވަހުން އެއުރެންގެ މެދުގައި ނިޔާކުރައްވާނެތެވެ.","",""],["₁₀ سورة يونس","94","فَإِن كُنتَ فِي شَكّٖ مِّمَّآ أَنزَلۡنَآ إِلَيۡكَ فَسۡـَٔلِ ٱلَّذِينَ يَقۡرَءُونَ ٱلۡكِتَٰبَ مِن قَبۡلِكَۚ لَقَدۡ جَآءَكَ ٱلۡحَقُّ مِن رَّبِّكَ فَلَا تَكُونَنَّ مِنَ ٱلۡمُمۡتَرِينَ ٩٤","فإن كنت في شك مما أنزلنا إليك فاسأل الذين يقرءون الكتاب من قبلك لقد جاءك الحق من ربك فلا تكونن من الممترين","ފަހެ، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ބާވައިލެއްވި ތަކެއްޗާމެދު، ކަލޭގެފާނު ޝައްކެއްގައިވާނަމަ، ކަލޭގެފާނުގެ ކުރިން ފޮތްކިޔައިއުޅުނު މީހުންނާ ސުވާލުކުރައްވާށެވެ! ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ކަލޭގެފާނަށް ހައްގު ތެދު އަތުވެއްޖެއެވެ. ފަހެ، ޝައްކުކުރާ މީހުންގެ ތެރެއިން، ކަލޭގެފާނު ވެވަޑައި ނުގަންނަވާ ހުށިކަމެވެ!","",""],["₁₀ سورة يونس","95","وَلَا تَكُونَنَّ مِنَ ٱلَّذِينَ كَذَّبُواْ بِـَٔايَٰتِ ٱللَّهِ فَتَكُونَ مِنَ ٱلۡخَٰسِرِينَ ٩٥","ولا تكونن من الذين كذبوا بآيات الله فتكون من الخاسرين","އަދި ﷲގެ އާޔަތްތައް ދޮގުކުރާ މީހުންގެ ތެރެއިން ކަލޭގެފާނު ވެވަޑައި ނުގަންނަވާހުށިކަމެވެ! ފަހެ، އޭރުން ކަލޭގެފާނު ވާހުށީ، ގެއްލި ހަލާކުވެގެންވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["₁₀ سورة يونس","96","إِنَّ ٱلَّذِينَ حَقَّتۡ عَلَيۡهِمۡ كَلِمَتُ رَبِّكَ لَا يُؤۡمِنُونَ ٩٦","إن الذين حقت عليهم كلمت ربك لا يؤمنون","ހަމަކަށަވަރުން، އެއުރެންގެ މައްޗަށް (އަޒާބު ހުރިކަމަށް) ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ބަސްފުޅު ހައްގު ވެގެންވާ މީހުން، އެއުރެންގެ ގާތަށް ކޮންމެ އާޔަތެއް އަޔަސް، އެއުރެންނަށް ވޭންދެނިވި އަޒާބު ފެނިއްޖައުމަށް ދާނދެން، އީމާނެއް ނުވާނެތެވެ.","",""],["₁₀ سورة يونس","97","وَلَوۡ جَآءَتۡهُمۡ كُلُّ ءَايَةٍ حَتَّىٰ يَرَوُاْ ٱلۡعَذَابَ ٱلۡأَلِيمَ ٩٧","ولو جاءتهم كل آية حتى يروا العذاب الأليم","ހަމަކަށަވަރުން، އެއުރެންގެ މައްޗަށް (އަޒާބު ހުރިކަމަށް) ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ބަސްފުޅު ހައްގު ވެގެންވާ މީހުން، އެއުރެންގެ ގާތަށް ކޮންމެ އާޔަތެއް އަޔަސް، އެއުރެންނަށް ވޭންދެނިވި އަޒާބު ފެނިއްޖައުމަށް ދާނދެން، އީމާނެއް ނުވާނެތެވެ.","",""],["₁₀ سورة يونس","98","فَلَوۡلَا كَانَتۡ قَرۡيَةٌ ءَامَنَتۡ فَنَفَعَهَآ إِيمَٰنُهَآ إِلَّا قَوۡمَ يُونُسَ لَمَّآ ءَامَنُواْ كَشَفۡنَا عَنۡهُمۡ عَذَابَ ٱلۡخِزۡيِ فِي ٱلۡحَيَوٰةِ ٱلدُّنۡيَا وَمَتَّعۡنَٰهُمۡ إِلَىٰ حِينٖ ٩٨","فلولا كانت قرية آمنت فنفعها إيمانها إلا قوم يونس لما آمنوا كشفنا عنهم عذاب الخزي في الحياة الدنيا ومتعناهم إلى حين","ފަހެ، ރަށެއްގެ މީހުން، އެއުރެންގެ އީމާންކަމުން މަންފާކުރާނޭ ގޮތުގައި، އީމާން ވީނަމަ ކިހާރަނގަޅުހޭ! އެހެނެއްކަމަކު، ޔޫނުސްގެފާނުގެ ގައުމުގެމީހުން އީމާން ވުމުން، ތިމަންރަސްކަލާނގެ އެއުރެންގެ ކިބައިން ދުނިޔޭގެ ހަޔާތުގައި ނިކަމެތިކަމުގެ އަޒާބު ދުރުކުރެއްވީމެވެ. އަދި އެއުރެންގެ އަޖަލު ޖެހިއްޖައުމަށް ދާނދެން، އެއުރެން އަރާމުގައި އުޅުމަށް ލެހެއްޓެވީމެވެ.","",""],["₁₀ سورة يونس","99","وَلَوۡ شَآءَ رَبُّكَ لَأٓمَنَ مَن فِي ٱلۡأَرۡضِ كُلُّهُمۡ جَمِيعًاۚ أَفَأَنتَ تُكۡرِهُ ٱلنَّاسَ حَتَّىٰ يَكُونُواْ مُؤۡمِنِينَ ٩٩","ولو شاء ربك لآمن من في الأرض كلهم جميعا أفأنت تكره الناس حتى يكونوا مؤمنين","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އިރާދަކުރައްވައިފިނަމަ، ބިމުގައި ވާހާ އެންމެން އީމާން ވެއްޖައީހެވެ. ފަހެ، ކަލޭގެފާނު މީސްތަކުންނަށް އެއުރެން މުއުމިނުން ކަމުގައިވުމަށް މަޖުބޫރުކުރައްވަނީތޯއެވެ؟","",""],["₁₀ سورة يونس","100","وَمَا كَانَ لِنَفۡسٍ أَن تُؤۡمِنَ إِلَّا بِإِذۡنِ ٱللَّهِۚ وَيَجۡعَلُ ٱلرِّجۡسَ عَلَى ٱلَّذِينَ لَا يَعۡقِلُونَ ١٠٠","وما كان لنفس أن تؤمن إلا بإذن الله ويجعل الرجس على الذين لا يعقلون","އަދި ﷲގެ އިޒުނަ ފުޅަށް މެނުވީ، އީމާން ވުމެއް އެއްވެސް ނަފްސަކަށް ނެތެވެ. އަދި ނުވިސްނާ މީހުންނަށް، އެކަލާނގެ އަޒާބު ދެއްވާހުށްޓެވެ.","",""],["₁₀ سورة يونس","101","قُلِ ٱنظُرُواْ مَاذَا فِي ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِۚ وَمَا تُغۡنِي ٱلۡأٓيَٰتُ وَٱلنُّذُرُ عَن قَوۡمٖ لَّا يُؤۡمِنُونَ ١٠١","قل انظروا ماذا في السماوات والأرض وما تغني الآيات والنذر عن قوم لا يؤمنون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އުޑުތަކާއި، ބިމުގައިވަނީ ކޮންއެއްޗެއްތޯ ތިޔަބައިމީހުން ބަލާށެވެ! އަދި އީމާން ނުވާ ބަޔަކަށް އާޔަތް ތަކުންނާއި، އިންޒާރުކުރައްވާ ރަސޫލުންގެ ކިބަޔަކުން ކަމެއް ފުއްދައެއް ނުދެވޭނެތެވެ.","",""],["₁₀ سورة يونس","102","فَهَلۡ يَنتَظِرُونَ إِلَّا مِثۡلَ أَيَّامِ ٱلَّذِينَ خَلَوۡاْ مِن قَبۡلِهِمۡۚ قُلۡ فَٱنتَظِرُوٓاْ إِنِّي مَعَكُم مِّنَ ٱلۡمُنتَظِرِينَ ١٠٢","فهل ينتظرون إلا مثل أيام الذين خلوا من قبلهم قل فانتظروا إني معكم من المنتظرين","ފަހެ، އެއުރެންގެ ކުރިން އިސްވެދިޔަ އުއްމަތްތަކަށް ޖެހުނުފަދަ ކަންތައްތަކެއް ޖެހުމަށްމެނުވީ، އެއުރެން އިންތިޒާރުކުރޭހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ފަހެ، ތިޔަބައިމީހުން އިންތިޒާރުކުރާށެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުވެސް، ތިޔަބައިމީހުންނާއެކު އިންތިޒާރުކުރާ މީހުންގެ ތެރެއިންވަމެވެ.","",""],["₁₀ سورة يونس","103","ثُمَّ نُنَجِّي رُسُلَنَا وَٱلَّذِينَ ءَامَنُواْۚ كَذَٰلِكَ حَقًّا عَلَيۡنَا نُنجِ ٱلۡمُؤۡمِنِينَ ١٠٣","ثم ننجي رسلنا والذين آمنوا كذلك حقا علينا ننج المؤمنين","ދެން ތިމަންރަސްކަލާނގެ ރަސޫލުންނާއި، އީމާންވި މީހުން ސަލާމަތް ކުރައްވަމެވެ. ހަމައެފަދައިން، މުއުމިނުން ދިންނަވައި ސަލާމަތް ކުރެއްވުމަކީ، ތިމަންރަސްކަލާނގެއަށް އޮތް ހައްގެކެވެ.","",""],["₁₀ سورة يونس","104","قُلۡ يَـٰٓأَيُّهَا ٱلنَّاسُ إِن كُنتُمۡ فِي شَكّٖ مِّن دِينِي فَلَآ أَعۡبُدُ ٱلَّذِينَ تَعۡبُدُونَ مِن دُونِ ٱللَّهِ وَلَٰكِنۡ أَعۡبُدُ ٱللَّهَ ٱلَّذِي يَتَوَفَّىٰكُمۡۖ وَأُمِرۡتُ أَنۡ أَكُونَ مِنَ ٱلۡمُؤۡمِنِينَ ١٠٤","قل يا أيها الناس إن كنتم في شك من ديني فلا أعبد الذين تعبدون من دون الله ولكن أعبد الله الذي يتوفاكم وأمرت أن أكون من المؤمنين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނުގެ ދީނާމެދު ޝައްކެއްގައި ވާނަމަވެސް، ﷲ ފިޔަވައި ތިޔަބައިމީހުން އަޅުކަންކުރާ ތަކެއްޗަކަށް، ތިމަންކަލޭގެފާނު އަޅުކަމެއް ނުކުރައްވާހުށީމެވެ. އެހެނެއްކަމަކު، ތިމަންކަލޭގެފާނު އަޅުކަންކުރައްވާހުށީ، ﷲއަށެވެ. އެކަލާނގެއީ، ތިޔަބައިމީހުން މަރުގަންނަވާ ރަސްކަލާނގެއެވެ. އަދި ތިމަންކަލޭގެފާނަށް އަމުރުކުރައްވާފައިވަނީ، މުއުމިނުންގެ ތެރެއިން ވުމަށެވެ.","",""],["₁₀ سورة يونس","105","وَأَنۡ أَقِمۡ وَجۡهَكَ لِلدِّينِ حَنِيفٗا وَلَا تَكُونَنَّ مِنَ ٱلۡمُشۡرِكِينَ ١٠٥","وأن أقم وجهك للدين حنيفا ولا تكونن من المشركين","އަދި ބާތިލު މަގުން އެއްކިބާވެ، ހައްގުގެ މަގަށް ތަބާ ވެގެންވާ ޙާލު، ކަލޭގެފާނުގެ މޫނުފުޅު އިސްލާމް ދީނާ ކުރިމަތިކުރައްވާށެވެ! އަދި ކަލޭގެފާނު މުޝްރިކުންގެ ތެރެއިން ވެވަޑައި ނުގަންނަވާހުށިކަމެވެ!","",""],["₁₀ سورة يونس","106","وَلَا تَدۡعُ مِن دُونِ ٱللَّهِ مَا لَا يَنفَعُكَ وَلَا يَضُرُّكَۖ فَإِن فَعَلۡتَ فَإِنَّكَ إِذٗا مِّنَ ٱلظَّـٰلِمِينَ ١٠٦","ولا تدع من دون الله ما لا ينفعك ولا يضرك فإن فعلت فإنك إذا من الظالمين","އަދި ﷲ ފިޔަވައި ކަލޭގެފާނަށް މަންފާއެއް ނުދެވޭ، އަދި ކަލޭގެފާނަށް ގެއްލުމެއްވެސް ނުދެވޭ ތަކެއްޗަށް، ކަލޭގެފާނު އަޅުކަން ނުކުރައްވާށެވެ! ފަހެ، ކަލޭގެފާނު އެކަންކުރައްވައިފިނަމަ، ހަމަކަށަވަރުން، އޭރުން ކަލޭގެފާނު ވާނީ އަނިޔާވެރިވި މީހުންގެ ތެރެއިންނެވެ.","",""],["₁₀ سورة يونس","107","وَإِن يَمۡسَسۡكَ ٱللَّهُ بِضُرّٖ فَلَا كَاشِفَ لَهُۥٓ إِلَّا هُوَۖ وَإِن يُرِدۡكَ بِخَيۡرٖ فَلَا رَآدَّ لِفَضۡلِهِۦۚ يُصِيبُ بِهِۦ مَن يَشَآءُ مِنۡ عِبَادِهِۦۚ وَهُوَ ٱلۡغَفُورُ ٱلرَّحِيمُ ١٠٧","وإن يمسسك الله بضر فلا كاشف له إلا هو وإن يردك بخير فلا راد لفضله يصيب به من يشاء من عباده وهو الغفور الرحيم","އަދި ﷲ ތިބާއަށް ގެއްލުމެއް މެދުވެރިކުރައްވާނަމަ، އެކަލާނގެ މެނުވީ، އެކަން ފިއްލަވާނޭ އެހެންފަރާތެއް ނުވެއެވެ. އަދި އެކަލާނގެ ކަލޭގެފާނަށް ހެޔޮކަމަކަށް އިރާދަކުރައްވައިފިނަމަ، އެކަލާނގެ ފަޟްލު ވަންތަކަން އަނބުރާ ރައްދުކުރެވޭނެ ފަރާތެއް ނުވެތެވެ. އެ ފަޟްލު ވަންތަކަން އެކަލާނގެ ދެއްވަނީ، އެކަލާނގެ އަޅުންގެ ތެރެއިން، އެކަލާނގެ އިރާދަކުރެއްވި މީހަކަށެވެ. އަދި އެކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₁₀ سورة يونس","108","قُلۡ يَـٰٓأَيُّهَا ٱلنَّاسُ قَدۡ جَآءَكُمُ ٱلۡحَقُّ مِن رَّبِّكُمۡۖ فَمَنِ ٱهۡتَدَىٰ فَإِنَّمَا يَهۡتَدِي لِنَفۡسِهِۦۖ وَمَن ضَلَّ فَإِنَّمَا يَضِلُّ عَلَيۡهَاۖ وَمَآ أَنَا۠ عَلَيۡكُم بِوَكِيلٖ ١٠٨","قل يا أيها الناس قد جاءكم الحق من ربكم فمن اهتدى فإنما يهتدي لنفسه ومن ضل فإنما يضل عليها وما أنا عليكم بوكيل","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން، ތިޔަބައިމީހުންގެ ގާތަށް ހައްގު އަތުވެއްޖެކަން ކަށަވަރެވެ. ފަހެ، ތެދުމަގު ލިބިގެންފި މީހަކު ތެދުމަގު ލިބިގަންނަކަން ކަށަވަރީ، އެމީހެއްގެ އަމިއްލަ ނަފްސަށެވެ. އަދި މަގުފުރެދިއްޖެ މީހަކު މަގުފުރެދޭކަން ކަށަވަރީ، އެމީހެއްގެ އަމިއްލަ ނަފްސުގެ މައްޗަށެވެ. އަދި ތިޔަބައިމީހުންގެ ކަންތައްތައް ޙަވާލުކުރައްވާފައިވާ ވަކީލަކު ކަމުގައި، ތިމަންކަލޭގެފާނު ނުވަމެވެ.","",""],["₁₀ سورة يونس","109","وَٱتَّبِعۡ مَا يُوحَىٰٓ إِلَيۡكَ وَٱصۡبِرۡ حَتَّىٰ يَحۡكُمَ ٱللَّهُۚ وَهُوَ خَيۡرُ ٱلۡحَٰكِمِينَ ١٠٩","واتبع ما يوحى إليك واصبر حتى يحكم الله وهو خير الحاكمين","އަދި ކަލޭގެފާނަށް ވަހީކުރައްވާ އެއްޗަކަށް، ކަލޭގެފާނު ތަބާ ވެވަޑައިގަންނަވާށެވެ! އަދި (އެއުރެންނާމެދު) ﷲ ހުކުމްކުރައްވައިފުމަށް ދާނދެން (ދީނަށް ގޮވައިލެއްވުމުގައި) ކެތްކުރައްވައިގެން ހުންނަވާށެވެ! އެކަލާނގެއީ، ހުކުމްކުރައްވާ އެންމެ ހެޔޮ ރަސްކަލާނގެއެވެ.","",""],["₁₁ سورة هود","1","بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ\n<br><br>\nالٓرۚ كِتَٰبٌ أُحۡكِمَتۡ ءَايَٰتُهُۥ ثُمَّ فُصِّلَتۡ مِن لَّدُنۡ حَكِيمٍ خَبِيرٍ ١","بسم الله الرحمن الرحيم الر كتاب أحكمت آياته ثم فصلت من لدن حكيم خبير","ا ل ر (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.) (މިއީ) ފޮތެކެވެ. އެ ފޮތުގެ އާޔަތްތައްވަނީ، އޮޅުމެއްނެތި މާނަ ސާފުކޮށް އެނގޭގޮތުގައި ފުރިހަމަ ނިޡާމަކުން ތަންޡީމްކުރައްވާފައެވެ. އަދި އެ (ފޮތުގައިވާ ހުރިހާ ތަކެއްޗެއް) ވަނީ ތަފްޞީލު ކޮށް ބަޔާންކުރައްވާފައެވެ. (އެއީ) މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެ ހަޒުރަތުންނެވެ.","",""],["₁₁ سورة هود","2","أَلَّا تَعۡبُدُوٓاْ إِلَّا ٱللَّهَۚ إِنَّنِي لَكُم مِّنۡهُ نَذِيرٞ وَبَشِيرٞ ٢","ألا تعبدوا إلا الله إنني لكم منه نذير وبشير","(އެއީ) ތިޔަބައިމީހުން ﷲއަށް މެނުވީ، އަޅުކަން ނުކުރުމަށެވެ. ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނީ، އެކަލާނގެ ހަޒުރަތުން ތިޔަބައިމީހުންގެ ގާތަށް ފޮނުއްވެވި، ބިރުވެރިކަމުގެ ޚަބަރު ދެއްވާ، އަދި އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާ ރަސޫލަކީމެވެ.","",""],["₁₁ سورة هود","3","وَأَنِ ٱسۡتَغۡفِرُواْ رَبَّكُمۡ ثُمَّ تُوبُوٓاْ إِلَيۡهِ يُمَتِّعۡكُم مَّتَٰعًا حَسَنًا إِلَىٰٓ أَجَلٖ مُّسَمّٗى وَيُؤۡتِ كُلَّ ذِي فَضۡلٖ فَضۡلَهُۥۖ وَإِن تَوَلَّوۡاْ فَإِنِّيٓ أَخَافُ عَلَيۡكُمۡ عَذَابَ يَوۡمٖ كَبِيرٍ ٣","وأن استغفروا ربكم ثم توبوا إليه يمتعكم متاعا حسنا إلى أجل مسمى ويؤت كل ذي فضل فضله وإن تولوا فإني أخاف عليكم عذاب يوم كبير","އަދި ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ފާފަފުއްސެވުން ތިޔަބައިމީހުން އެދޭށެވެ! އަދި އެކަލާނގެއަށް ތިޔަބައިމީހުން ތައުބާ ވާށެވެ! އޭރުން ކަނޑައެޅިގެންވާ އަޖަލު ހަމަވެއްޖައުމަށް ދާނދެން، ރަނގަޅު ދިރިއުޅުމެއްގައި އެކަލާނގެ ތިޔަބައިމީހުން ލަހައްޓަވާނެތެވެ. އަދި ޢަމަލު އިތުރުކުރި ކޮންމެ މީހަކަށް، އެމީހަކު އިތުރުކުރި ޢަމަލެއްގެ ޖަޒާ (ގިޔާމަތް ދުވަހުން) އެކަލާނގެ ދެއްވާނެތެވެ. ތިޔަބައިމީހުން ފުރަގަސްދޭނަމަ، ފަހެ، ހަމަކަށަވަރުން، ބޮޑުވެގެންވާ ދުވަހެއްގެ އަޒާބާމެދު، ތިޔަބައިމީހުންގެ މައްޗަށް ތިމަންކަލޭގެފާނު ބިރުފުޅުގަނެތެވެ.","",""],["₁₁ سورة هود","4","إِلَى ٱللَّهِ مَرۡجِعُكُمۡۖ وَهُوَ عَلَىٰ كُلِّ شَيۡءٖ قَدِيرٌ ٤","إلى الله مرجعكم وهو على كل شيء قدير","ތިޔަބައިމީހުން އެނބުރި ދިއުންވަނީ، ﷲގެ ހަޒުރަތަށެވެ. އަދި އެކަލާނގެއީ، ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₁₁ سورة هود","5","أَلَآ إِنَّهُمۡ يَثۡنُونَ صُدُورَهُمۡ لِيَسۡتَخۡفُواْ مِنۡهُۚ أَلَا حِينَ يَسۡتَغۡشُونَ ثِيَابَهُمۡ يَعۡلَمُ مَا يُسِرُّونَ وَمَا يُعۡلِنُونَۚ إِنَّهُۥ عَلِيمُۢ بِذَاتِ ٱلصُّدُورِ ٥","ألا إنهم يثنون صدورهم ليستخفوا منه ألا حين يستغشون ثيابهم يعلم ما يسرون وما يعلنون إنه عليم بذات الصدور","ދަންނާށެވެ! ހަމަކަށަވަރުން، އެއުރެން، އެއުރެންގެ މޭތައް އަނެއްފަރާތަށް އަނބުރާލަތެވެ. (އެއީ) އެކަލާނގެއަށް ވަންހަނާވެގަތުމަށެވެ. ދަންނާށެވެ! އެއުރެންގެ ފޭރާމުން އެއުރެން ފޮރުވިގެން ތިބޭއިރުވެސް، އެއުރެން ސިއްރުކުރާ ކަންތަކާއި، ފާޅުކުރާ ކަންތައް، އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ހިތްތަކުގައިވާހާ ކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₁₁ سورة هود","6","۞وَمَا مِن دَآبَّةٖ فِي ٱلۡأَرۡضِ إِلَّا عَلَى ٱللَّهِ رِزۡقُهَا وَيَعۡلَمُ مُسۡتَقَرَّهَا وَمُسۡتَوۡدَعَهَاۚ كُلّٞ فِي كِتَٰبٖ مُّبِينٖ ٦","وما من دابة في الأرض إلا على الله رزقها ويعلم مستقرها ومستودعها كل في كتاب مبين","ބިމުގައި ހިނގާބިނގާ އުޅޭ ދިރޭ އެއްޗެހީގެ ތެރެއިން، އެ އެއްޗަކަށް ﷲ ރިޒުގު ނުދެއްވާ އެއްވެސް އެއްޗެއް ނުވެތެވެ. އެ ތަކެތި ބިމުގައިއުޅޭ ތަނާއި، މަރުވެގެން ވަޅުލާތަނެއް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. މި ހުރިހާ ކަމެއްވަނީ ބަޔާންވެގެންވާ ފޮތެއްގައި ލިޔުއްވާފައެވެ.","",""],["₁₁ سورة هود","7","وَهُوَ ٱلَّذِي خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضَ فِي سِتَّةِ أَيَّامٖ وَكَانَ عَرۡشُهُۥ عَلَى ٱلۡمَآءِ لِيَبۡلُوَكُمۡ أَيُّكُمۡ أَحۡسَنُ عَمَلٗاۗ وَلَئِن قُلۡتَ إِنَّكُم مَّبۡعُوثُونَ مِنۢ بَعۡدِ ٱلۡمَوۡتِ لَيَقُولَنَّ ٱلَّذِينَ كَفَرُوٓاْ إِنۡ هَٰذَآ إِلَّا سِحۡرٞ مُّبِينٞ ٧","وهو الذي خلق السماوات والأرض في ستة أيام وكان عرشه على الماء ليبلوكم أيكم أحسن عملا ولئن قلت إنكم مبعوثون من بعد الموت ليقولن الذين كفروا إن هذا إلا سحر مبين","އަދި އެކަލާނގެއީ، ހަ ދުވަހުގެ ތެރޭގައި އުޑުތަކާއި ބިން ހެއްދެވި ރަސްކަލާނގެއެވެ. އެކަލާނގެ ޢަރްޝު (އޭރު) ވަނީ ފެން މަތީގައެވެ. (އެއީ) ތިޔަބައިމީހުންގެ ތެރެއިން، އެންމެ ޢަމަލު ރަނގަޅީ ކާކުތޯ އިމްތިހާނުކުރެއްވުމަށެވެ. އަދި މަރުވުމަށްފަހު، ހަމަކަށަވަރުން، ތިޔަބައިމީހުން އަލުން ދިރުއްވައި، މަހުޝަރަށް ފޮނުއްވާނެޔޭ ކަލޭގެފާނު ވިދާޅުވެއްޖެނަމަ، ހަމަކަށަވަރުން، ކާފިރުވި މީހުން ބުނާނެތެވެ. މިއީ، ބަޔާންވެގެންވާ ޖާދޫއެއްކަމުގައި މެނުވީ ނުވެތެވެ.","",""],["₁₁ سورة هود","8","وَلَئِنۡ أَخَّرۡنَا عَنۡهُمُ ٱلۡعَذَابَ إِلَىٰٓ أُمَّةٖ مَّعۡدُودَةٖ لَّيَقُولُنَّ مَا يَحۡبِسُهُۥٓۗ أَلَا يَوۡمَ يَأۡتِيهِمۡ لَيۡسَ مَصۡرُوفًا عَنۡهُمۡ وَحَاقَ بِهِم مَّا كَانُواْ بِهِۦ يَسۡتَهۡزِءُونَ ٨","ولئن أخرنا عنهم العذاب إلى أمة معدودة ليقولن ما يحبسه ألا يوم يأتيهم ليس مصروفا عنهم وحاق بهم ما كانوا به يستهزئون","އަދި އަދަދުކުރައްވާފައިވާ ވަގުތުކޮޅަކަށް، ތިމަންރަސްކަލާނގެ އެއުރެންގެ ކިބައިން އަޒާބު ފަސްކުރައްވައިފިނަމަ، ހަމަކަށަވަރުން، އެއުރެން ބުނާނެތެވެ. އެ އަޒާބު އަޔަނުދީ ބަންދުކުރަނީ، ކޮންއެއްޗެއްހެއްޔެވެ؟ ދަންނާށެވެ! އެއުރެންނަށް އަޒާބު އަންނަ ދުވަހު އެއުރެންގެ ކިބައިން އެ އަޒާބު ދުރުނުކުރައްވާ ހުށްޓެވެ. އަދި އެއުރެން އެއަށް ފުރައްސާރަކޮށް އުޅުނު އަޒާބު، އެއުރެން ވަށައިލާ ހުށްޓެވެ.","",""],["₁₁ سورة هود","9","وَلَئِنۡ أَذَقۡنَا ٱلۡإِنسَٰنَ مِنَّا رَحۡمَةٗ ثُمَّ نَزَعۡنَٰهَا مِنۡهُ إِنَّهُۥ لَيَـُٔوسٞ كَفُورٞ ٩","ولئن أذقنا الإنسان منا رحمة ثم نزعناها منه إنه ليئوس كفور","އަދި ތިމަންރަސްކަލާނގެ އިންސާނާއަށް ރަހުމަތެއް ލައްވައި، ދެން އޭނާގެ ކިބައިން ތިމަންރަސްކަލާނގެ އެ ރަހުމަތް ނިގުޅައިގަންނަވައިފިނަމަ، ހަމަކަށަވަރުން، އޭނާ ވަނީ، ތިމަންރަސްކަލާނގެ ރަހުމަތުން އުންމީދުކަނޑައި، ނިއުމަތަށް ދެކޮޅުހަދާ ކާފިރަކަށެވެ.","",""],["₁₁ سورة هود","10","وَلَئِنۡ أَذَقۡنَٰهُ نَعۡمَآءَ بَعۡدَ ضَرَّآءَ مَسَّتۡهُ لَيَقُولَنَّ ذَهَبَ ٱلسَّيِّـَٔاتُ عَنِّيٓۚ إِنَّهُۥ لَفَرِحٞ فَخُورٌ ١٠","ولئن أذقناه نعماء بعد ضراء مسته ليقولن ذهب السيئات عني إنه لفرح فخور","އަދި، އެ އިންސާނާއަށް ޖެހުނު މުސީބަތަކަށްފަހު، ތިމަންރަސްކަލާނގެ އޭނާއަށް ނިއުމަތް ދެއްވައިފިނަމަ، އޭނާ ބުނާނެކަން ކަށަވަރެވެ. ތިމަންގެ ކިބައިން ހުރިހާ މުސީބަތެއް ފިލައި ހިނގައްޖެއެވެ. ހަމަކަށަވަރުން، އޭނާ ވަނީ (އެ ލިބުނު ކަންތަކަށް) އުފާވެ ފަޚުރުވެރިވެފައެވެ.","",""],["₁₁ سورة هود","11","إِلَّا ٱلَّذِينَ صَبَرُواْ وَعَمِلُواْ ٱلصَّـٰلِحَٰتِ أُوْلَـٰٓئِكَ لَهُم مَّغۡفِرَةٞ وَأَجۡرٞ كَبِيرٞ ١١","إلا الذين صبروا وعملوا الصالحات أولئك لهم مغفرة وأجر كبير","ކެތްތެރިވެ، ސާލިހު ޢަމަލުތައްކުރި މީހުން މެނުވީއެވެ. އެއުރެންނަށް، ފާފަފުއްސެވުމާއި، ބޮޑުވެގެންވާ ދަރުމަހުށްޓެވެ.","",""],["₁₁ سورة هود","12","فَلَعَلَّكَ تَارِكُۢ بَعۡضَ مَا يُوحَىٰٓ إِلَيۡكَ وَضَآئِقُۢ بِهِۦ صَدۡرُكَ أَن يَقُولُواْ لَوۡلَآ أُنزِلَ عَلَيۡهِ كَنزٌ أَوۡ جَآءَ مَعَهُۥ مَلَكٌۚ إِنَّمَآ أَنتَ نَذِيرٞۚ وَٱللَّهُ عَلَىٰ كُلِّ شَيۡءٖ وَكِيلٌ ١٢","فلعلك تارك بعض ما يوحى إليك وضائق به صدرك أن يقولوا لولا أنزل عليه كنز أو جاء معه ملك إنما أنت نذير والله على كل شيء وكيل","ފަހެ، އެކަލޭގެފާނަށް ޚަޒާނާއެއް ބާވައިނުލެއްވީ ކީއްވެހޭ، ނުވަތަ އެކަލޭގެފާނުގެ އަރިހުގައި މަލާއިކަތަކު ވަޑައިނުގަތީކީއްވެހޭ، އެއުރެން ބުނެފާނެކަމަށްޓަކައި، ކަލޭގެފާނަށް ވަހީކުރައްވާ ތަކެތިން ބައެއް، ކަލޭގެފާނު ދޫކޮށްލައްވައިފާނެ ހެއްޔެވެ؟ (އެބަހީ: ދޫކޮށެއްނުލައްވާނެތެވެ.) އަދި އެ ތަކެތި ކިޔަވައި ވިދާޅުވުމުން، ކަލޭގެފާނުގެ ހިތްޕުޅު ދަތިވެސްވެދާނެތެވެ. ކަލޭގެފާނު ވާކަން ކަށަވަރީ، ބިރުވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު ކަމުގައެވެ. އަދި ﷲއީ، ހުރިހާ ތަކެއްޗެއް ރައްކާތެރިކުރައްވައި، ބަލަހައްޓަވާ ރަސްކަލާނގެއެވެ.","",""],["₁₁ سورة هود","13","أَمۡ يَقُولُونَ ٱفۡتَرَىٰهُۖ قُلۡ فَأۡتُواْ بِعَشۡرِ سُوَرٖ مِّثۡلِهِۦ مُفۡتَرَيَٰتٖ وَٱدۡعُواْ مَنِ ٱسۡتَطَعۡتُم مِّن دُونِ ٱللَّهِ إِن كُنتُمۡ صَٰدِقِينَ ١٣","أم يقولون افتراه قل فأتوا بعشر سور مثله مفتريات وادعوا من استطعتم من دون الله إن كنتم صادقين","ނުވަތަ އެކަލޭގެފާނު އަމިއްލަފުޅަށް ހެއްދެވި އާޔަތް ތަކެއް ކަމަށް އެއުރެން ބުނަނީ ހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ފަހެ، އަމިއްލައަށް ހަދާފައިވާ އެކަހަލަ ދިހަ ސޫރަތް ތިޔަބައިމީހުން ގެނެސްބަލާށެވެ! އަދި ތިޔަބައިމީހުން ތެދުވެރިން ކަމުގައިވަނީނަމަ، اللًّه ފިޔަވައި ތިޔަބައިމީހުންނަށް ކުޅަދާނަވީހާ ބަޔަކަށް ނިކަން ގޮވައިގެނެސްބަލާށެވެ!","",""],["₁₁ سورة هود","14","فَإِلَّمۡ يَسۡتَجِيبُواْ لَكُمۡ فَٱعۡلَمُوٓاْ أَنَّمَآ أُنزِلَ بِعِلۡمِ ٱللَّهِ وَأَن لَّآ إِلَٰهَ إِلَّا هُوَۖ فَهَلۡ أَنتُم مُّسۡلِمُونَ ١٤","فإلم يستجيبوا لكم فاعلموا أنما أنزل بعلم الله وأن لا إله إلا هو فهل أنتم مسلمون","ފަހެ، އެއުރެން ތިޔަބައިމީހުންނަށް އިޖާބަ ނުދީފިނަމަ، ފަހެ، ތިޔަބައިމީހުން ދަންނާށެވެ! އެ އާޔަތްތައް ބާވައިލައްވާފައިވަނީ، ﷲގެ ދެނެވޮޑިގަތުމާ އެކުގައެވެ. އަދި އެކަލާނގެ މެނުވީ، ހައްގު ވެގެން އަޅުކަމެއްވެވޭ އިލާހަކު ނުވެތެވެ. ފަހެ، ތިޔަބައިމީހުން މުސްލިމުން ކަމުގައި ވާނޫހެއްޔެވެ؟","",""],["₁₁ سورة هود","15","مَن كَانَ يُرِيدُ ٱلۡحَيَوٰةَ ٱلدُّنۡيَا وَزِينَتَهَا نُوَفِّ إِلَيۡهِمۡ أَعۡمَٰلَهُمۡ فِيهَا وَهُمۡ فِيهَا لَا يُبۡخَسُونَ ١٥","من كان يريد الحياة الدنيا وزينتها نوف إليهم أعمالهم فيها وهم فيها لا يبخسون","ދުނިޔޭގެ ދިރިއުޅުމާއި، އެ ދުނިޔޭގެ ޒީނަތްތެރިކަމަށް އެދޭމީހާ (ދަންނާށެވެ!) އެއުރެންގެ ޢަމަލުތައް ތިމަންރަސްކަލާނގެ އެއުރެންނަށް އެތާނގައި ހަމަޔަށް ފުއްދަވައި ދެއްވާހުށީމެވެ. އަދި އެއުރެންނަށް އެތާނގައި އުނި ނުކުރައްވާހުށްޓެވެ.","",""],["₁₁ سورة هود","16","أُوْلَـٰٓئِكَ ٱلَّذِينَ لَيۡسَ لَهُمۡ فِي ٱلۡأٓخِرَةِ إِلَّا ٱلنَّارُۖ وَحَبِطَ مَا صَنَعُواْ فِيهَا وَبَٰطِلٞ مَّا كَانُواْ يَعۡمَلُونَ ١٦","أولئك الذين ليس لهم في الآخرة إلا النار وحبط ما صنعوا فيها وباطل ما كانوا يعملون","އެއުރެންނީ އާޚިރަތުގައި ނަރަކަ ނޫން އެހެންތަނެއް އެއުރެންނަށް ނުވާ މީހުންނެވެ. އަދި އެއުރެންކުޅަ ކަންތައް އެތާނގައި، ބޭކާރުވެގެންވެތެވެ. އަދި އެއުރެން ކޮށްއުޅުނު ކަންތައް ބާތިލު ވެގެންވެތެވެ.","",""],["₁₁ سورة هود","17","أَفَمَن كَانَ عَلَىٰ بَيِّنَةٖ مِّن رَّبِّهِۦ وَيَتۡلُوهُ شَاهِدٞ مِّنۡهُ وَمِن قَبۡلِهِۦ كِتَٰبُ مُوسَىٰٓ إِمَامٗا وَرَحۡمَةًۚ أُوْلَـٰٓئِكَ يُؤۡمِنُونَ بِهِۦۚ وَمَن يَكۡفُرۡ بِهِۦ مِنَ ٱلۡأَحۡزَابِ فَٱلنَّارُ مَوۡعِدُهُۥۚ فَلَا تَكُ فِي مِرۡيَةٖ مِّنۡهُۚ إِنَّهُ ٱلۡحَقُّ مِن رَّبِّكَ وَلَٰكِنَّ أَكۡثَرَ ٱلنَّاسِ لَا يُؤۡمِنُونَ ١٧","أفمن كان على بينة من ربه ويتلوه شاهد منه ومن قبله كتاب موسى إماما ورحمة أولئك يؤمنون به ومن يكفر به من الأحزاب فالنار موعده فلا تك في مرية منه إنه الحق من ربك ولكن أكثر الناس لا يؤمنون","ފަހެ، އެމީހެއްގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ބަޔާންވެގެންވާ ހެތްކެއްގެ މަތީގައި ހުރި މީހާވެސް ހެއްޔެވެ؟ (އެބަހީ: އެފަދަ މީހާއާއި، އިސްވެދިޔަ އާޔަތުގައި ބަޔާން ވެގެންވާ މީހުންނާ އެއްގޮތެއްނޫނެވެ.) އަދި އެކަލާނގެ ހަޒުރަތުން ފޮނުއްވި ހެތްކެއް، އެއާވިދިގެން އާދެތެވެ. އަދި އޭގެކުރިން އިމާމެއްގެ ގޮތުގައްޔާއި، ރަހުމަތެއްގެ ގޮތުގައި މޫސާގެފާނުގެ ފޮތް އޮތެވެ. އެއުރެން (އެބަހީ: ހެތްކެއްގެ މަތީގައިވާ މީހުން) އެއަށް އީމާން ވެތެވެ. އަދި ޖަމާއަތްތަކުގެ ތެރެއިން އެ ފޮތަށް ކާފިރުވާ މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް ވައުދުކުރައްވާފައިވާ ތަނަކީ، ނަރަކައެވެ. ފަހެ، ކަލޭގެފާނު އެކަމާމެދު ޝައްކެއްގައި ނުހުންނަވާށެވެ! ހަމަކަށަވަރުން، އެއީ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައި ހައްގު ގޮތެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުން (އެއަކަށް) އީމާނެއް ނުވެތެވެ.","",""],["₁₁ سورة هود","18","وَمَنۡ أَظۡلَمُ مِمَّنِ ٱفۡتَرَىٰ عَلَى ٱللَّهِ كَذِبًاۚ أُوْلَـٰٓئِكَ يُعۡرَضُونَ عَلَىٰ رَبِّهِمۡ وَيَقُولُ ٱلۡأَشۡهَٰدُ هَـٰٓؤُلَآءِ ٱلَّذِينَ كَذَبُواْ عَلَىٰ رَبِّهِمۡۚ أَلَا لَعۡنَةُ ٱللَّهِ عَلَى ٱلظَّـٰلِمِينَ ١٨","ومن أظلم ممن افترى على الله كذبا أولئك يعرضون على ربهم ويقول الأشهاد هؤلاء الذين كذبوا على ربهم ألا لعنة الله على الظالمين","ﷲއާމެދު ހަދައިގެން ދޮގެއްބުނި މީހަކަށްވުރެ، އަނިޔާވެރިކަން ބޮޑީ ކާކުހެއްޔެވެ؟ އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް އެއުރެން ހުށަހެޅޭނެތެވެ. އަދި ހެކިން ބުނާނެތެވެ. އެއުރެންގެ ވެރިރަސްކަލާނގެއާމެދު ދޮގުހަދައިގެން އުޅުނު މީހުންނަކީ މިތިބީއެވެ. ދަންނާށެވެ! އަނިޔާވެރިންގެ މައްޗަށް ﷲގެ ލައުނަތް ހުށްޓެވެ.","",""],["₁₁ سورة هود","19","ٱلَّذِينَ يَصُدُّونَ عَن سَبِيلِ ٱللَّهِ وَيَبۡغُونَهَا عِوَجٗا وَهُم بِٱلۡأٓخِرَةِ هُمۡ كَٰفِرُونَ ١٩","الذين يصدون عن سبيل الله ويبغونها عوجا وهم بالآخرة هم كافرون","އެއުރެންނީ ﷲގެ މަގުން (މީސްތަކުން) އެއްކިބާކުރާ މީހުންނެވެ. އަދި އެ މަގު ގުދުމަގަކަށްވުމަށް އެދޭ މީހުންނެވެ. އަދި އެއުރެންނީ އާޚިރަތް ދުވަހަށް ކާފިރު ވެގެން ތިބޭ މީހުންނެވެ.","",""],["₁₁ سورة هود","20","أُوْلَـٰٓئِكَ لَمۡ يَكُونُواْ مُعۡجِزِينَ فِي ٱلۡأَرۡضِ وَمَا كَانَ لَهُم مِّن دُونِ ٱللَّهِ مِنۡ أَوۡلِيَآءَۘ يُضَٰعَفُ لَهُمُ ٱلۡعَذَابُۚ مَا كَانُواْ يَسۡتَطِيعُونَ ٱلسَّمۡعَ وَمَا كَانُواْ يُبۡصِرُونَ ٢٠","أولئك لم يكونوا معجزين في الأرض وما كان لهم من دون الله من أولياء يضاعف لهم العذاب ما كانوا يستطيعون السمع وما كانوا يبصرون","އެއުރެންނީ ބިމުގައި (ﷲ) ނުކުޅައްދައިލެވޭނޭ ބަޔަކު ކަމުގައި ނުވެތެވެ. އަދި ﷲ ފިޔަވައި އެއުރެންނަށް އެހީތެރިވާނޭ ބަޔަކު ނުވެތެވެ. އެއުރެންނަށް އަޒާބު ގިނަގުނަކުރައްވާ ހުށްޓެވެ. (ހައްގު ބަސްފުޅު) އެހުމަށް ކުޅަދާނަވެގެންވާ ބަޔަކު ކަމުގައި އެއުރެން ނުވެތެވެ. އަދި (ހައްގު މަގު) ފެންނަ ބަޔަކުކަމުގައިވެސް، އެއުރެން ނުމެވޭމެއެވެ.","",""],["₁₁ سورة هود","21","أُوْلَـٰٓئِكَ ٱلَّذِينَ خَسِرُوٓاْ أَنفُسَهُمۡ وَضَلَّ عَنۡهُم مَّا كَانُواْ يَفۡتَرُونَ ٢١","أولئك الذين خسروا أنفسهم وضل عنهم ما كانوا يفترون","އެއުރެންނީ، އެއުރެންގެ އަމިއްލަ ނަފްސުތައް ގެއްލެނިކުޅަ މީހުންނެވެ. އަދި އެއުރެން ހަދައި އުޅުނު ދޮގުތައް، އެއުރެންގެ ކިބައިން ގެއްލިގެން ހިނގައްޖެއެވެ.","",""],["₁₁ سورة هود","22","لَا جَرَمَ أَنَّهُمۡ فِي ٱلۡأٓخِرَةِ هُمُ ٱلۡأَخۡسَرُونَ ٢٢","لا جرم أنهم في الآخرة هم الأخسرون","ޝައްކެއްނެތެވެ. އާޚިރަތުގައި އެންމެ ބޮޑަށް ގެއްލެނިވެގެންވާ ބަޔަކީ، ހަމަ އެއުރެންނެވެ.","",""],["₁₁ سورة هود","23","إِنَّ ٱلَّذِينَ ءَامَنُواْ وَعَمِلُواْ ٱلصَّـٰلِحَٰتِ وَأَخۡبَتُوٓاْ إِلَىٰ رَبِّهِمۡ أُوْلَـٰٓئِكَ أَصۡحَٰبُ ٱلۡجَنَّةِۖ هُمۡ فِيهَا خَٰلِدُونَ ٢٣","إن الذين آمنوا وعملوا الصالحات وأخبتوا إلى ربهم أولئك أصحاب الجنة هم فيها خالدون","ހަމަކަށަވަރުން، އީމާންވެ، ސާލިހު ޢަމަލުތައްކޮށް، އަދި އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް މަޑުމޮޅިވީ މީހުންނީ، ސުވަރުގޭގެ އަހުލުވެރިންނެވެ. އެއުރެން އެތާނގައި ދެމިތިބޭނެތެވެ.","",""],["₁₁ سورة هود","24","۞مَثَلُ ٱلۡفَرِيقَيۡنِ كَٱلۡأَعۡمَىٰ وَٱلۡأَصَمِّ وَٱلۡبَصِيرِ وَٱلسَّمِيعِۚ هَلۡ يَسۡتَوِيَانِ مَثَلًاۚ أَفَلَا تَذَكَّرُونَ ٢٤","مثل الفريقين كالأعمى والأصم والبصير والسميع هل يستويان مثلا أفلا تذكرون","އެ ދެބައިމީހުންގެ މިސާލު، ކަނުމީހާއާއި، ބީރުމީހާއާއި، ލޮލަށް ފެންނަމީހާއާއި، އިވޭމީހާ ފަދައެވެ. އެ ދެބައިމީހުން މިސާލުގެ ގޮތުން ހަމަހަމަވެގެން ވޭހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުން ހަނދުމަ ނުކުރަނީހެއްޔެވެ؟","",""],["₁₁ سورة هود","25","وَلَقَدۡ أَرۡسَلۡنَا نُوحًا إِلَىٰ قَوۡمِهِۦٓ إِنِّي لَكُمۡ نَذِيرٞ مُّبِينٌ ٢٥","ولقد أرسلنا نوحا إلى قومه إني لكم نذير مبين","ހަމަކަށަވަރުން، ނޫޙުގެފާނު، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ގާތަށް ތިމަންރަސްކަލާނގެ ފޮނުއްވީމެވެ. (ވިދާޅުވެ އެންގެވުމަށެވެ.) ހަމަކަށަވަރުން، އަހުރެންނީ، ތިޔަބައިމީހުންގެ ގާތަށް ފޮނުއްވެވި، ބަޔާން ވެގެންހުރި އިންޒާރުކުރާ މީޙަކީމެވެ.","",""],["₁₁ سورة هود","26","أَن لَّا تَعۡبُدُوٓاْ إِلَّا ٱللَّهَۖ إِنِّيٓ أَخَافُ عَلَيۡكُمۡ عَذَابَ يَوۡمٍ أَلِيمٖ ٢٦","أن لا تعبدوا إلا الله إني أخاف عليكم عذاب يوم أليم","ﷲއަށް މެނުވީ، ތިޔަބައިމީހުން އަޅުކަން ނުކުރާހުށިކަމެވެ! ހަމަކަށަވަރުން ވޭންދެނިވި ދުވަހެއްގެ އަޒާބަށް ތިޔަބައިމީހުންނާމެދު ތިމަންކަލޭގެފާނު ބިރުފުޅުގަނެއެވެ.","",""],["₁₁ سورة هود","27","فَقَالَ ٱلۡمَلَأُ ٱلَّذِينَ كَفَرُواْ مِن قَوۡمِهِۦ مَا نَرَىٰكَ إِلَّا بَشَرٗا مِّثۡلَنَا وَمَا نَرَىٰكَ ٱتَّبَعَكَ إِلَّا ٱلَّذِينَ هُمۡ أَرَاذِلُنَا بَادِيَ ٱلرَّأۡيِ وَمَا نَرَىٰ لَكُمۡ عَلَيۡنَا مِن فَضۡلِۭ بَلۡ نَظُنُّكُمۡ كَٰذِبِينَ ٢٧","فقال الملأ الذين كفروا من قومه ما نراك إلا بشرا مثلنا وما نراك اتبعك إلا الذين هم أراذلنا بادي الرأي وما نرى لكم علينا من فضل بل نظنكم كاذبين","ފަހެ، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންކުރެ، ކާފިރުވި ބޮޑުން ބުނެފޫއެވެ. ތިމަންމެންކަހަލަ އާދަމުގެދަރިޔަކު ކަމުގައި މެނުވީ ތިމަންމެން، ކަލޭގެފާނު ނުދެކެމުއެވެ. އަދި ކަލޭގެފާނަށް ތަބާވި މީހުންނަކީ، ތިމަންމެންގެ ތެރެއިން އެންމެ ދެރަ ނިކަމެތިން ކަމުގައި މެނުވީ ތިމަންމެން ނުދެކެމުއެވެ. (އެއުރެން ތަބާ ވީ) މަތިމަތިން ފެންނަ ފެނުމަށެވެ. އަދި ތިމަންމެންގެ މައްޗަށް އެއްވެސް މޮޅުކަމެއް ތިޔަބައިމީހުންނަށް ލިބިގެންވާ ކަމަކަށް ތިމަންމެން ނުދެކެމުއެވެ. އަދި ކިއެއްތަ! ތިމަންމެން ހީކުރަނީ، ތިޔަބައިމީހުންނަކީ ދޮގުހަދާ ބަޔަކުކަމުގައެވެ.","",""],["₁₁ سورة هود","28","قَالَ يَٰقَوۡمِ أَرَءَيۡتُمۡ إِن كُنتُ عَلَىٰ بَيِّنَةٖ مِّن رَّبِّي وَءَاتَىٰنِي رَحۡمَةٗ مِّنۡ عِندِهِۦ فَعُمِّيَتۡ عَلَيۡكُمۡ أَنُلۡزِمُكُمُوهَا وَأَنتُمۡ لَهَا كَٰرِهُونَ ٢٨","قال يا قوم أرأيتم إن كنت على بينة من ربي وآتاني رحمة من عنده فعميت عليكم أنلزمكموها وأنتم لها كارهون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން ނިކަން ބުނެބަލާށެވެ! އަހުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައި ފާޅުވެގެންވާ ތެދުމަގެއްގައި އަހުރެންވީނަމަ، އަދި އެކަލާނގެ ހަޒުރަތުން އަހުރެންނަށް ރަހުމަތެއް ދެއްވައިފިނަމަ، ދެން އެކަންތައް ތިޔަބައިމީހުންނަށް ވަންހަނާކުރެއްވިހިނދު، ތިޔަބައިމީހުން އެކަމަށް ނުރުހުންވެ ތިއްބައި، އަހުރެމެންނަށް ތިޔަބައިމީހުންގެ މައްޗަށް އެކަން ލާޒިމްކުރެވިދާނެ ހެއްޔެވެ؟","",""],["₁₁ سورة هود","29","وَيَٰقَوۡمِ لَآ أَسۡـَٔلُكُمۡ عَلَيۡهِ مَالًاۖ إِنۡ أَجۡرِيَ إِلَّا عَلَى ٱللَّهِۚ وَمَآ أَنَا۠ بِطَارِدِ ٱلَّذِينَ ءَامَنُوٓاْۚ إِنَّهُم مُّلَٰقُواْ رَبِّهِمۡ وَلَٰكِنِّيٓ أَرَىٰكُمۡ قَوۡمٗا تَجۡهَلُونَ ٢٩","ويا قوم لا أسألكم عليه مالا إن أجري إلا على الله وما أنا بطارد الذين آمنوا إنهم ملاقو ربهم ولكني أراكم قوما تجهلون","އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! އެކަމުގެ މައްޗަށް އެއްވެސް މުދަލެއް ތިޔަބައިމީހުންގެ ކިބަޔަކުން ނޭދެމެވެ. ތިމަންކަލޭގެފާނުގެ އުޖޫރަ، ﷲގެ ހަޒުރަތުން ނޫނީ ނުވެއެވެ. އަދި އީމާން ވެއްޖެ މީސްތަކުން ފަހައި ބޭރުކުރާ މީހަކު ކަމުގައި ތިމަންކަލޭގެފާނު ނުވަމެވެ. ހަމަކަށަވަރުން، އެއުރެންނީ، އެއުރެންގެ ވެރިރަސްކަލާނގެއާ ބައްދަލުވާނޭ ބަޔެކެވެ. އެހެނެއްކަމަކު، ތިޔަބައިމީހުންނީ، ޖާހިލު ބަޔަކު ކަމުގައި ތިމަންކަލޭގެފާނު ދެކެވަޑައިގަންނަވަމެވެ.","",""],["₁₁ سورة هود","30","وَيَٰقَوۡمِ مَن يَنصُرُنِي مِنَ ٱللَّهِ إِن طَرَدتُّهُمۡۚ أَفَلَا تَذَكَّرُونَ ٣٠","ويا قوم من ينصرني من الله إن طردتهم أفلا تذكرون","އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! އަހުރެން، އެއުރެން ފަހައި ބޭރުކޮށްފިނަމަ، ﷲގެ އަޒާބުން އަހުރެން ސަލާމަތްކޮށް ނަސްރު ދޭނީ ކާކުހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުން ހަނދުމަ ނުކުރަނީހެއްޔެވެ؟","",""],["₁₁ سورة هود","31","وَلَآ أَقُولُ لَكُمۡ عِندِي خَزَآئِنُ ٱللَّهِ وَلَآ أَعۡلَمُ ٱلۡغَيۡبَ وَلَآ أَقُولُ إِنِّي مَلَكٞ وَلَآ أَقُولُ لِلَّذِينَ تَزۡدَرِيٓ أَعۡيُنُكُمۡ لَن يُؤۡتِيَهُمُ ٱللَّهُ خَيۡرًاۖ ٱللَّهُ أَعۡلَمُ بِمَا فِيٓ أَنفُسِهِمۡ إِنِّيٓ إِذٗا لَّمِنَ ٱلظَّـٰلِمِينَ ٣١","ولا أقول لكم عندي خزائن الله ولا أعلم الغيب ولا أقول إني ملك ولا أقول للذين تزدري أعينكم لن يؤتيهم الله خيرا الله أعلم بما في أنفسهم إني إذا لمن الظالمين","އަދި ﷲގެ ޚަޒާނާތައް ތިމަންކަލޭގެފާނުގެ އަރިހުގައި ވެއެކޭ ތިޔަބައިމީހުންނަކަށް ވިދާޅެއް ނުވަމެވެ. އަދި ތިމަންކަލޭގެފާނަކަށް ޣައިބެއްވެސް އެނގިވަޑައެއް ނުގަނެތެވެ. އަދި ތިމަންކަލޭގެފާނީ، މަލާއިކަތް އެކޭވެސް ވިދާޅެއް ނުވަމެވެ. އަދި ތިޔަބައިމީހުންގެ ލޯތަކުން، ނިކަމެތިކޮށްހިތާ މީހުންނާމެދު، އެއުރެންނަށް، އެއްވެސް ހެވެއް ﷲ ނުދެއްވާނެކަމަކަށްވެސް ތިމަންކަލޭގެފާނު ވިދާޅެއް ނުވަމެވެ. އެއުރެންގެ ހިތްތަކުގައިވާ ކަންތައް، އެންމެމޮޅަށް ދެނެވޮޑިގެންވަނީ، ﷲއެވެ. (އެފަދަ އެއްޗެއް ތިމަންކަލޭގެފާނު ވިދާޅުވިނަމަ) އެހިނދު ތިމަންކަލޭގެފާނު ވާހުށީ، އަނިޔާވެރިންގެ ތެރެއިންކަން ކަށަވަރެވެ.","",""],["₁₁ سورة هود","32","قَالُواْ يَٰنُوحُ قَدۡ جَٰدَلۡتَنَا فَأَكۡثَرۡتَ جِدَٰلَنَا فَأۡتِنَا بِمَا تَعِدُنَآ إِن كُنتَ مِنَ ٱلصَّـٰدِقِينَ ٣٢","قالوا يا نوح قد جادلتنا فأكثرت جدالنا فأتنا بما تعدنا إن كنت من الصادقين","އެއުރެން ދެންނެވޫއެވެ. އޭ ނޫޙުގެފާނެވެ! ހަމަކަށަވަރުން، ކަލޭގެފާނު ތިމަންމެންނާ ޖަދަލުކުރައްވައިފީމުއެވެ. އަދި ތިމަންމެންނާ ޖަދަލުކުރެއްވުން ގިނަކުރައްވައިފީމުއެވެ. ފަހެ، ކަލޭގެފާނުވަނީ، ތެދުވެރިންގެ ތެރެއިން ކަމުގައިވާނަމަ، ތިމަންމެންނަށް ތިޔަ ވައުދުކުރައްވާ ކަންތައް ތިމަންމެންނާ ހަމަޔަށް ގެންނަވައި ބައްލަވާށެވެ!","",""],["₁₁ سورة هود","33","قَالَ إِنَّمَا يَأۡتِيكُم بِهِ ٱللَّهُ إِن شَآءَ وَمَآ أَنتُم بِمُعۡجِزِينَ ٣٣","قال إنما يأتيكم به الله إن شاء وما أنتم بمعجزين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އެކަލާނގެ އިރާދަކުރައްވައިފިނަމަ، އެކަންތައްތައް ތިޔަބައިމީހުންނާ ހަމަޔަށް ގެންނަވާހުށިކަން ކަށަވަރީ، ﷲއެވެ. އަދި ތިޔަބައިމީހުންނަކީ، އެކަލާނގެ ނުކުޅައްދައި، ރެކިގެންދާނޭ ބަޔަކު ކަމުގައި ނުވެތެވެ.","",""],["₁₁ سورة هود","34","وَلَا يَنفَعُكُمۡ نُصۡحِيٓ إِنۡ أَرَدتُّ أَنۡ أَنصَحَ لَكُمۡ إِن كَانَ ٱللَّهُ يُرِيدُ أَن يُغۡوِيَكُمۡۚ هُوَ رَبُّكُمۡ وَإِلَيۡهِ تُرۡجَعُونَ ٣٤","ولا ينفعكم نصحي إن أردت أن أنصح لكم إن كان الله يريد أن يغويكم هو ربكم وإليه ترجعون","ތިޔަބައިމީހުން މަގުފުރެއްދެވުމަށް ﷲ އިރާދަކުރައްވާ ކަމުގައިވީނަމަ، ތިޔަބައިމީހުންނަށް ނަސޭހަތް ދެއްވަން ތިމަންކަލޭގެފާނު އެދިވަޑައިގަތަސް، ތިމަންކަލޭގެފާނުގެ ނަސޭހަތަކުން ތިޔަބައިމީހުންނަކަށް މަންފާއެއް ނުކުރާނެތެވެ. އެކަލާނގެއީ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއެވެ. އަދި ތިޔަބައިމީހުން ރުޖޫއަކުރައްވާހުށީ، އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["₁₁ سورة هود","35","أَمۡ يَقُولُونَ ٱفۡتَرَىٰهُۖ قُلۡ إِنِ ٱفۡتَرَيۡتُهُۥ فَعَلَيَّ إِجۡرَامِي وَأَنَا۠ بَرِيٓءٞ مِّمَّا تُجۡرِمُونَ ٣٥","أم يقولون افتراه قل إن افتريته فعلي إجرامي وأنا بريء مما تجرمون","ނުވަތަ އެކަލޭގެފާނު އަމިއްލަފުޅަށް އެ ގުރްއާން ހެއްދެވިކަމަށް އެއުރެން ބުނަނީހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނު އެ ގުރްއާން އަމިއްލަފުޅަށް ހެއްދެވިނަމަ، ފަހެ، އެކަމުގެ ކުށް އޮތީ ތިމަންކަލޭގެފާނުގެ މައްޗަށެވެ. އަދި ތިޔަބައިމީހުން ކުރަމުންގެންދާ ކަންތަކުގެ ކުށުން، ތިމަންކަލޭގެފާނު ބަރީއަވެގެންވަމެވެ.","",""],["₁₁ سورة هود","36","وَأُوحِيَ إِلَىٰ نُوحٍ أَنَّهُۥ لَن يُؤۡمِنَ مِن قَوۡمِكَ إِلَّا مَن قَدۡ ءَامَنَ فَلَا تَبۡتَئِسۡ بِمَا كَانُواْ يَفۡعَلُونَ ٣٦","وأوحي إلى نوح أنه لن يؤمن من قومك إلا من قد آمن فلا تبتئس بما كانوا يفعلون","ނޫޙުގެފާނަށް ވަހީ އިއްވެވިއެވެ. ކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ތެރެއިން މިހާތަނަށް އީމާން ވެގެންތިބި މީހުން މެނުވީ، އީމާނެއް ނުވާނެތެވެ. ފަހެ، އެއުރެން ކޮށްއުޅޭ ކަންތަކާމެދު، ކަލޭގެފާނު ހިތާމަ ނުކުރައްވާށެވެ!","",""],["₁₁ سورة هود","37","وَٱصۡنَعِ ٱلۡفُلۡكَ بِأَعۡيُنِنَا وَوَحۡيِنَا وَلَا تُخَٰطِبۡنِي فِي ٱلَّذِينَ ظَلَمُوٓاْ إِنَّهُم مُّغۡرَقُونَ ٣٧","واصنع الفلك بأعيننا ووحينا ولا تخاطبني في الذين ظلموا إنهم مغرقون","އަދި ތިމަންރަސްކަލާނގެ ބެއްލެވުމުގެ ދަށުން، އަދި ތިމަންރަސްކަލާނގެ ވަހީއާއެކު، ކަލޭގެފާނު ނާކޮޅު ބަންނަވާށެވެ! އަދި އަނިޔާވެރިވި މީހުންނާ މެދުގައި، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ނުދަންނަވާށެވެ! ހަމަކަށަވަރުން، އެއުރެންނަކީ، ޣަރަގުކުރައްވާނޭ ބަޔެކެވެ.","",""],["₁₁ سورة هود","38","وَيَصۡنَعُ ٱلۡفُلۡكَ وَكُلَّمَا مَرَّ عَلَيۡهِ مَلَأٞ مِّن قَوۡمِهِۦ سَخِرُواْ مِنۡهُۚ قَالَ إِن تَسۡخَرُواْ مِنَّا فَإِنَّا نَسۡخَرُ مِنكُمۡ كَمَا تَسۡخَرُونَ ٣٨","ويصنع الفلك وكلما مر عليه ملأ من قومه سخروا منه قال إن تسخروا منا فإنا نسخر منكم كما تسخرون","އަދި އެކަލޭގެފާނު ނާކޮޅު ބަންނަވަމުން ގެންދެވިއެވެ. އެކަލޭގެފާނުގެ ގައުމުގެމީހުންކުރެ، ބޮޑުންގެ ބަޔަކު އެކަލޭގެފާނުގެ އަރިހުންލާފައި ހިނގައްޖެ ކޮންމެ ފަހަރަކު، އެކަލޭގެފާނަށް މަލާމާތްކުރެތެވެ. އެކަލޭގެފާނު ވިދާޅުވެތެވެ. ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނަށް މަލާމާތްކުރާނަމަ، ތިޔަބައިމީހުން މަލާމާތްކުރާ ފަދައިން، ހަމަކަށަވަރުން، ތިމަންމެންވެސް ތިޔަބައިމީހުންނަށް މަލާމާތް ކުރާނަމެވެ.","",""],["₁₁ سورة هود","39","فَسَوۡفَ تَعۡلَمُونَ مَن يَأۡتِيهِ عَذَابٞ يُخۡزِيهِ وَيَحِلُّ عَلَيۡهِ عَذَابٞ مُّقِيمٌ ٣٩","فسوف تعلمون من يأتيه عذاب يخزيه ويحل عليه عذاب مقيم","ފަހެ، ނިކަމެތިކަން އެމީހަކަށް ދެނިވި އަޒާބު، އެމީހަކާ ހަމައަށް އަންނަނީ، އަދި ދެމިހުންނަނިވި އަޒާބު، އެމީހަކަށް ކުރިމަތިވެގެން އަންނަނީ، ކާކަށްކަން ނިކަންހުރެ ތިޔަބައިމީހުންނަށް އެނގޭނެތެވެ.","",""],["₁₁ سورة هود","40","حَتَّىٰٓ إِذَا جَآءَ أَمۡرُنَا وَفَارَ ٱلتَّنُّورُ قُلۡنَا ٱحۡمِلۡ فِيهَا مِن كُلّٖ زَوۡجَيۡنِ ٱثۡنَيۡنِ وَأَهۡلَكَ إِلَّا مَن سَبَقَ عَلَيۡهِ ٱلۡقَوۡلُ وَمَنۡ ءَامَنَۚ وَمَآ ءَامَنَ مَعَهُۥٓ إِلَّا قَلِيلٞ ٤٠","حتى إذا جاء أمرنا وفار التنور قلنا احمل فيها من كل زوجين اثنين وأهلك إلا من سبق عليه القول ومن آمن وما آمن معه إلا قليل","ތިމަންރަސްކަލާނގެ އަމުރުފުޅު އައިސް، އަދި އުނދުނުގެ ތެރެއިން ފެން އަރައި އުތުރިގެންފުމަށް ދާނދެނެވެ. (އެހިނދު) ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވީމެވެ. ކޮންމެ އެއްޗަކުން (އަންހެން ފިރިހެން) ދެ ޖިންސުގެ ދޭއްޗާއި، އަދި ހަލާކުވެ ނެތިދިއުމުގެ ބަސްފުޅު، އިސްވެގޮސްފައިވާ މީހަކު ފިޔަވައި، ކަލޭގެފާނުގެ އަހުލުވެރިންނާއި، އީމާން ވެގެންތިބި މީހުން އެ ނާކޮޅަށް ލައްވާށެވެ! މަދު މީހަކު މެނުވީ، އެކަލޭގެފާނުގެ އަރިހުގައި އީމާން ވެގެނެއް ނުވެތެވެ.","",""],["₁₁ سورة هود","41","۞وَقَالَ ٱرۡكَبُواْ فِيهَا بِسۡمِ ٱللَّهِ مَجۡرٜىٰهَا وَمُرۡسَىٰهَآۚ إِنَّ رَبِّي لَغَفُورٞ رَّحِيمٞ ٤١","وقال اركبوا فيها بسم الله مجراها ومرساها إن ربي لغفور رحيم","އަދި އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން އެ ނާކޮޅަށް އަރާށެވެ! އެ ނާކޮޅު ދުވުމާއި، ބަނދަރުކުރުންވަނީ، ﷲގެ އިސްމު ފުޅުންނެވެ. ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₁₁ سورة هود","42","وَهِيَ تَجۡرِي بِهِمۡ فِي مَوۡجٖ كَٱلۡجِبَالِ وَنَادَىٰ نُوحٌ ٱبۡنَهُۥ وَكَانَ فِي مَعۡزِلٖ يَٰبُنَيَّ ٱرۡكَب مَّعَنَا وَلَا تَكُن مَّعَ ٱلۡكَٰفِرِينَ ٤٢","وهي تجري بهم في موج كالجبال ونادى نوح ابنه وكان في معزل يا بني اركب معنا ولا تكن مع الكافرين","އަދި ފަރުބަދަތައް ފަދަ ރާޅުތަކެއްގެ ތެރޭގައި، އެއުރެންނާއިގެން އެ ނާކޮޅު ދުވަމުންދެއެވެ. އަދި ނޫޙުގެފާނު އެކަލޭގެފާނުގެ ދަރިކަލުންނަށް ގޮވައިލެއްވިއެވެ. އޭރު އެ ދަރިކަލުންވީ (އެހެންމީހުންނާ) ވަކިން ދުރުގައެވެ. އޭ ދަރިފުޅާއެވެ! ތިމަންމެންނާއެކު (ނާކޮޅަށް) އަރާށެވެ! އަދި ކާފިރުންނާ އެކުގައި ނުވާށެވެ!","",""],["₁₁ سورة هود","43","قَالَ سَـَٔاوِيٓ إِلَىٰ جَبَلٖ يَعۡصِمُنِي مِنَ ٱلۡمَآءِۚ قَالَ لَا عَاصِمَ ٱلۡيَوۡمَ مِنۡ أَمۡرِ ٱللَّهِ إِلَّا مَن رَّحِمَۚ وَحَالَ بَيۡنَهُمَا ٱلۡمَوۡجُ فَكَانَ مِنَ ٱلۡمُغۡرَقِينَ ٤٣","قال سآوي إلى جبل يعصمني من الماء قال لا عاصم اليوم من أمر الله إلا من رحم وحال بينهما الموج فكان من المغرقين","އެ ދަރިކަލުން ދެންނެވިއެވެ. ފެނުން، ތިމަން ރައްކާތެރިކުރާނޭ ފަރުބަދައަކަށް ތިމަން ހިނގައިދާހުށީމެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ﷲގެ އަމުރުފުޅުން (އެބަހީ: ﷲގެ އަޒާބުން) ރައްކާތެރިކުރާނޭ ފަރާތެއް، އެކަލާނގެ ރަހުމަތް ލެއްވި މީހަކަށް މެނުވީ މިއަދަކު ނެތެވެ. އަދި އެ ދެބަފައިކަލުންގެ ދެމެދުގައި ރާޅު ހުރަސްއެޅިއެވެ. އަދި ޣަރަގުކުރެއްވި މީހުންގެ ތެރެއިން، އެ ދަރިކަލުންވިއެވެ.","",""],["₁₁ سورة هود","44","وَقِيلَ يَـٰٓأَرۡضُ ٱبۡلَعِي مَآءَكِ وَيَٰسَمَآءُ أَقۡلِعِي وَغِيضَ ٱلۡمَآءُ وَقُضِيَ ٱلۡأَمۡرُ وَٱسۡتَوَتۡ عَلَى ٱلۡجُودِيِّۖ وَقِيلَ بُعۡدٗا لِّلۡقَوۡمِ ٱلظَّـٰلِمِينَ ٤٤","وقيل يا أرض ابلعي ماءك ويا سماء أقلعي وغيض الماء وقضي الأمر واستوت على الجودي وقيل بعدا للقوم الظالمين","އަދި އެންގެވިއެވެ. އޭ ބިމާއެވެ! ތިޔަ ބިމުގެ ފެންގަނޑު ދިރުވައިލާށެވެ! އަދި އޭ އުޑާއެވެ! ވެހުން ހުއްޓައިލާށެވެ! ދެން ފެންގަނޑު ހިނދިއްޖެއެވެ. އަދި (އެއުރެން ހަލާކުވެދިއުމުގެ) ކަންތައްވެ ނިމިއްޖެއެވެ. އަދި ޖޫދިއްޔު ފަރުބަދައިގެ މައްޗަށް އެ (ނާކޮޅު) ބީހި، ހަމަޖެހިއްޖެއެވެ. އަދި އެންގެވިއެވެ. އަނިޔާވެރިވީ މީހުންނަށް ހަލާކާއި ގެއްލުން ހުށްޓެވެ.","",""],["₁₁ سورة هود","45","وَنَادَىٰ نُوحٞ رَّبَّهُۥ فَقَالَ رَبِّ إِنَّ ٱبۡنِي مِنۡ أَهۡلِي وَإِنَّ وَعۡدَكَ ٱلۡحَقُّ وَأَنتَ أَحۡكَمُ ٱلۡحَٰكِمِينَ ٤٥","ونادى نوح ربه فقال رب إن ابني من أهلي وإن وعدك الحق وأنت أحكم الحاكمين","ނޫޙުގެފާނު، އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް މުނާޖާ ދެންނެވިއެވެ. ފަހެ، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. މި އަޅާގެ ވެރިރަސްކަލާކޯއެވެ! ހަމަކަށަވަރުން، މި އަޅާގެ ދަރި ވަނީ، މި އަޅާގެ އަހުލުވެރިންގެ ތެރެއިންނެވެ. އަދި ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެ ވައުދު ފުޅަކީ، ހައްގު ބަސްފުޅެވެ. އަދި އިބަރަސްކަލާނގެއީ، ހުކުމްކުރައްވާ، އެންމެ ޢަދުލުވެރި ރަސްކަލާނގެއެވެ.","",""],["₁₁ سورة هود","46","قَالَ يَٰنُوحُ إِنَّهُۥ لَيۡسَ مِنۡ أَهۡلِكَۖ إِنَّهُۥ عَمَلٌ غَيۡرُ صَٰلِحٖۖ فَلَا تَسۡـَٔلۡنِ مَا لَيۡسَ لَكَ بِهِۦ عِلۡمٌۖ إِنِّيٓ أَعِظُكَ أَن تَكُونَ مِنَ ٱلۡجَٰهِلِينَ ٤٦","قال يا نوح إنه ليس من أهلك إنه عمل غير صالح فلا تسألن ما ليس لك به علم إني أعظك أن تكون من الجاهلين","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. އޭ ނޫޙުގެފާނެވެ! ހަމަކަށަވަރުން، އެ ދަރިކަލުން، ކަލޭގެފާނުގެ އަހުލުވެރިންގެ ތެރެޔަކުން ނުވެއެވެ. ހަމަކަށަވަރުން، އެ ދަރިކަލުންގެ ޢަމަލަކީ، ރަނގަޅުނޫން ޢަމަލެކެވެ. ފަހެ، ކަލޭގެފާނަށް އެކަމަކާމެދު، އެނގުމެއްނުވާ ކަންތަކަށްއެދި، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ނުދަންނަވާށެވެ! ހަމަކަށަވަރުން، ޖާހިލުންގެ ތެރެއިން ކަލޭގެފާނު ވެދާނެތީ، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ނަސޭހަތް ތެރިވެވޮޑިގެންވަމެވެ.","",""],["₁₁ سورة هود","47","قَالَ رَبِّ إِنِّيٓ أَعُوذُ بِكَ أَنۡ أَسۡـَٔلَكَ مَا لَيۡسَ لِي بِهِۦ عِلۡمٞۖ وَإِلَّا تَغۡفِرۡ لِي وَتَرۡحَمۡنِيٓ أَكُن مِّنَ ٱلۡخَٰسِرِينَ ٤٧","قال رب إني أعوذ بك أن أسألك ما ليس لي به علم وإلا تغفر لي وترحمني أكن من الخاسرين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިމަންއަޅާގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، ތިމަން އަޅާއަށް، އެކަމަކާމެދު އެނގުމެއްނުވާކަމަކަށް، އިބަރަސްކަލާނގެ ހަޒުރަތަށް އެދި ދެންނެވުމުން، ތިމަންއަޅާ ސަލާމަތްކުރެއްވުންއެދި، އިބަރަސްކަލާނގެ ހަޒުރަތުން ވާގިއެދި، ރައްކާތެރިކަން ލިބިގަންނަމެވެ. އިބަރަސްކަލާނގެ ތިމަން އަޅާޔަށް ފާފަ ނުފުއްސަވާނަމަ، އަދި ރަހުމަތް ނުލައްވާނަމަ، ގެއްލެނިވެގެންވާ މީހުންގެ ތެރެއިން ތިމަންއަޅާ ވެދާހުށްޓެވެ.","",""],["₁₁ سورة هود","48","قِيلَ يَٰنُوحُ ٱهۡبِطۡ بِسَلَٰمٖ مِّنَّا وَبَرَكَٰتٍ عَلَيۡكَ وَعَلَىٰٓ أُمَمٖ مِّمَّن مَّعَكَۚ وَأُمَمٞ سَنُمَتِّعُهُمۡ ثُمَّ يَمَسُّهُم مِّنَّا عَذَابٌ أَلِيمٞ ٤٨","قيل يا نوح اهبط بسلام منا وبركات عليك وعلى أمم ممن معك وأمم سنمتعهم ثم يمسهم منا عذاب أليم","އެންގެވިއެވެ. އޭ ނޫޙުގެފާނެވެ! ތިމަންރަސްކަލާނގެ ހަޒުރަތުން އަމާންކަމަކާއެކު، އަދި ކަލޭގެފާނާއި، ކަލޭގެފާނުގެ އަރިހުގައިވާ މީހުންގެ ތެރެއިން އުފެދޭ އުއްމަތްތަކަށް ބަރަކާތާއެކު (ނާކޮޅުން) ފައިބައިވަޑައިގަންނަވާށެވެ! އަދި އުއްމަތް ތަކެއްވެއެވެ. ތިމަންރަސްކަލާނގެ އެ އުއްމަތްތަކަށް (ދުނިޔޭގައި) އުފަލާއި، އަރާމު ދެއްވާހުށީމެވެ. ދެން ތިމަންރަސްކަލާނގެ ހަޒުރަތުން އެއުރެންނަށް ވޭންދެނިވި އަޒާބެއް އައިސްޖެހޭނެތެވެ.","",""],["₁₁ سورة هود","49","تِلۡكَ مِنۡ أَنۢبَآءِ ٱلۡغَيۡبِ نُوحِيهَآ إِلَيۡكَۖ مَا كُنتَ تَعۡلَمُهَآ أَنتَ وَلَا قَوۡمُكَ مِن قَبۡلِ هَٰذَاۖ فَٱصۡبِرۡۖ إِنَّ ٱلۡعَٰقِبَةَ لِلۡمُتَّقِينَ ٤٩","تلك من أنباء الغيب نوحيها إليك ما كنت تعلمها أنت ولا قومك من قبل هذا فاصبر إن العاقبة للمتقين","އެއީ، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ވަހީކުރައްވާ ޣައިބުގެ ޚަބަރުތަކުގެ ތެރެއިން ޚަބަރު ތަކެކެވެ. ކަލޭގެފާނަކަށްވެސް، އަދި ކަލޭގެފާނުންގެ ގައުމުގެމީހުންނަކަށްވެސް، މީގެކުރިޔަކުން އެ ޚަބަރުތައް އެނގިވަޑައިގެންފައެއް ނުވެތެވެ. ފަހެ، ކަލޭގެފާނު ކެތްކުރައްވާށެވެ! ހަމަކަށަވަރުން (ހެޔޮ) ނިމުންވަނީ، ތަގުވާވެރިންނަށެވެ.","",""],["₁₁ سورة هود","50","وَإِلَىٰ عَادٍ أَخَاهُمۡ هُودٗاۚ قَالَ يَٰقَوۡمِ ٱعۡبُدُواْ ٱللَّهَ مَا لَكُم مِّنۡ إِلَٰهٍ غَيۡرُهُۥٓۖ إِنۡ أَنتُمۡ إِلَّا مُفۡتَرُونَ ٥٠","وإلى عاد أخاهم هودا قال يا قوم اعبدوا الله ما لكم من إله غيره إن أنتم إلا مفترون","އަދި ތިމަންރަސްކަލާނގެ ޢާދު ބާގައިމީހުންގެ ގާތަށް، އެއުރެންގެ އަޚު ހޫދުގެފާނު (ފޮނުއްވީމެވެ.) އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން ﷲއަށް އަޅުކަންކުރާށެވެ! އެކަލާނގެ ފިޔަވައި އެހެން އިލާހަކު ތިޔަބައިމީހުންނަކަށް ނުވެތެވެ. ތިޔަބައިމީހުންނީ، ދޮގުހަދާ ބަޔަކު ކަމުގައި ނޫނީ ނުވެތެވެ.","",""],["₁₁ سورة هود","51","يَٰقَوۡمِ لَآ أَسۡـَٔلُكُمۡ عَلَيۡهِ أَجۡرًاۖ إِنۡ أَجۡرِيَ إِلَّا عَلَى ٱلَّذِي فَطَرَنِيٓۚ أَفَلَا تَعۡقِلُونَ ٥١","يا قوم لا أسألكم عليه أجرا إن أجري إلا على الذي فطرني أفلا تعقلون","އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! އަހުރެން، ތިޔަބައިމީހުންގެ ކިބަޔަކުން އެކަމުގެ މައްޗަށް އުޖޫރައަކަށް ނޭދެމެވެ. އަހުރެންގެ އުޖޫރަ، އަހުރެން އުފެއްދެވި ފަރާތުން މެނުވީ ނުވެއެވެ. ފަހެ، ތިޔަބައިމީހުންނަކަށް ނުވިސްނޭހެއްޔެވެ؟","",""],["₁₁ سورة هود","52","وَيَٰقَوۡمِ ٱسۡتَغۡفِرُواْ رَبَّكُمۡ ثُمَّ تُوبُوٓاْ إِلَيۡهِ يُرۡسِلِ ٱلسَّمَآءَ عَلَيۡكُم مِّدۡرَارٗا وَيَزِدۡكُمۡ قُوَّةً إِلَىٰ قُوَّتِكُمۡ وَلَا تَتَوَلَّوۡاْ مُجۡرِمِينَ ٥٢","ويا قوم استغفروا ربكم ثم توبوا إليه يرسل السماء عليكم مدرارا ويزدكم قوة إلى قوتكم ولا تتولوا مجرمين","އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް، ފާފަފުއްސެވުންއެދި ދަންނަވާށެވެ. ދެން އެކަލާނގެއަށް ތައުބާ ވާށެވެ! އޭރުން، ތިޔަބައިމީހުންގެ މައްޗަށް އުޑުން، ބޯކޮށް ގިނައިން (ވެހޭގޮތުގައި) ވާރޭ ފޮނުއްވާނެތެވެ. އަދި ތިޔަބައިމީހުންގެ ބާރުގެ ތެރެޔަށް ބާރު އިތުރުކޮށްދެއްވާނެތެވެ. އަދި ކުށްވެރިންގެ ގޮތުގައި ތިޔަބައިމީހުން ފުރަގަސްދީ ނުދާށެވެ!","",""],["₁₁ سورة هود","53","قَالُواْ يَٰهُودُ مَا جِئۡتَنَا بِبَيِّنَةٖ وَمَا نَحۡنُ بِتَارِكِيٓ ءَالِهَتِنَا عَن قَوۡلِكَ وَمَا نَحۡنُ لَكَ بِمُؤۡمِنِينَ ٥٣","قالوا يا هود ما جئتنا ببينة وما نحن بتاركي آلهتنا عن قولك وما نحن لك بمؤمنين","އެއުރެން ދެންނެވޫއެވެ. އޭ ހޫދުގެފާނެވެ! ބަޔާންވެގެންވާ ހެތްކެއް ތިމަންމެންގެ ގާތަކަށް ކަލޭގެފާނު ނުގެންނަވަމުއެވެ. އަދި (ހަމައެކަނި) ކަލޭގެފާނުގެ ބަސްފުޅަކަށް ތިމަންމެންގެ އިލާހު ންތައް ދޫކޮށްލާނޭ ބަޔަކު ކަމުގައި ތިމަންމެން ނުވަމުއެވެ. އަދި ކަލޭގެފާނަށް އީމާންވާ ބަޔަކު ކަމުގައި، ތިމަންމެން ނުވާހުށީމެވެ.","",""],["₁₁ سورة هود","54","إِن نَّقُولُ إِلَّا ٱعۡتَرَىٰكَ بَعۡضُ ءَالِهَتِنَا بِسُوٓءٖۗ قَالَ إِنِّيٓ أُشۡهِدُ ٱللَّهَ وَٱشۡهَدُوٓاْ أَنِّي بَرِيٓءٞ مِّمَّا تُشۡرِكُونَ ٥٤","إن نقول إلا اعتراك بعض آلهتنا بسوء قال إني أشهد الله واشهدوا أني بريء مما تشركون","ތިމަންމެންގެ ބައެއް އިލާހުން ކަލޭގެފާނަށް ނުބައި ކަމެއް ޖައްސައިފިކަމުގައި މެނުވީ ތިމަންމެން ނުބުނާނޫއެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ޝަރީކު ކޮށް އުޅޭ ތަކެތިން، ތިމަންކަލޭގެފާނު ބަރީއަވެގެންވާކަމަށް ﷲ ހެކިކުރައްވަމެވެ. އަދި ތިޔަބައިމީހުންވެސް ހެކިވާށެވެ!","",""],["₁₁ سورة هود","55","مِن دُونِهِۦۖ فَكِيدُونِي جَمِيعٗا ثُمَّ لَا تُنظِرُونِ ٥٥","من دونه فكيدوني جميعا ثم لا تنظرون","އެކަލާނގެ ފިޔަވައި އެހެން ފަރާތްތަކުންނެވެ. (އެބަހީ: އެހެން ފަރާތްތަކުން ތިމަންކަލޭގެފާނު ބަރީއަ ވެގެންވަމެވެ.) ފަހެ، ތިޔަބައިމީހުން އެންމެން ތިމަންކަލޭގެފާނަށް (ހަލާކު ދިނުމަށް) ރޭވުންތައް ރާވާށެވެ! ދެން ތިމަންކަލޭގެފާނަށް ލަސްކުރާނެކަމެއް ނެތެވެ.","",""],["₁₁ سورة هود","56","إِنِّي تَوَكَّلۡتُ عَلَى ٱللَّهِ رَبِّي وَرَبِّكُمۚ مَّا مِن دَآبَّةٍ إِلَّا هُوَ ءَاخِذُۢ بِنَاصِيَتِهَآۚ إِنَّ رَبِّي عَلَىٰ صِرَٰطٖ مُّسۡتَقِيمٖ ٥٦","إني توكلت على الله ربي وربكم ما من دابة إلا هو آخذ بناصيتها إن ربي على صراط مستقيم","ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުންގެ ވެރި އަދި ތިޔަބައިމީހުންގެ ވެރި ﷲއަށް ތިމަންކަލޭގެފާނު ވަކީލު ކޮށްފީމެވެ. ހިނގާބިނގާ އުޅޭ އެއްވެސް ދިރޭ އެއްޗެއް، އެ އެއްޗެއްގެ ނާޞިޔަތުގައި، އެކަލާނގެ ހިއްޕަވާ ޙާލު ގައިވާ ކަމުގައި މެނުވީ ނުވެތެވެ. ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ވޮޑިގެންވަނީ، ސީދާވެގެންވާ މަގުގައެވެ. (ނޯޓު: ނާޞިޔަތަކީ، ނިތްކުރިމަތީގެ އިސްތަށިގަނޑެވެ. ނާޞިޔަތުގައި ހިއްޕެވުމުގެ މުރާދަކީ، ހުރިހައި ބާރެއް އެކަލާނގެއަށް މަލަކަ ވެގެންވުމެވެ.)","",""],["₁₁ سورة هود","57","فَإِن تَوَلَّوۡاْ فَقَدۡ أَبۡلَغۡتُكُم مَّآ أُرۡسِلۡتُ بِهِۦٓ إِلَيۡكُمۡۚ وَيَسۡتَخۡلِفُ رَبِّي قَوۡمًا غَيۡرَكُمۡ وَلَا تَضُرُّونَهُۥ شَيۡـًٔاۚ إِنَّ رَبِّي عَلَىٰ كُلِّ شَيۡءٍ حَفِيظٞ ٥٧","فإن تولوا فقد أبلغتكم ما أرسلت به إليكم ويستخلف ربي قوما غيركم ولا تضرونه شيئا إن ربي على كل شيء حفيظ","ފަހެ، ތިޔަބައިމީހުން އެނބުރި، ފުރަގަސްދޭނަމަ (ދަންނާށެވެ!) ތިޔަބައިމީހުންގެ ގާތަށް، އެކަމަކާއިގެން ތިމަންކަލޭގެފާނު ފޮނުއްވެވި ކަންތައް، ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށް ތިމަންކަލޭގެފާނު އިއްވަވައިފީމެވެ. އަދި ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، ތިޔަބައިމީހުންގެ ބަދަލުގައި، ތިޔަބައިމީހުން ނޫންބަޔަކު ގެންނަވާނެތެވެ. އަދި ތިޔަބައިމީހުންނަކަށް، އެއްވެސް ކަމަކުން އެކަލާނގެއަކަށް ގެއްލުމެއް ނުދެވޭހުށްޓެވެ. ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ކޮންމެ އެއްޗެއް ރައްކާތެރިކުރައްވައި، ބަލަހައްޓަވާ ރަސްކަލާނގެއެވެ.","",""],["₁₁ سورة هود","58","وَلَمَّا جَآءَ أَمۡرُنَا نَجَّيۡنَا هُودٗا وَٱلَّذِينَ ءَامَنُواْ مَعَهُۥ بِرَحۡمَةٖ مِّنَّا وَنَجَّيۡنَٰهُم مِّنۡ عَذَابٍ غَلِيظٖ ٥٨","ولما جاء أمرنا نجينا هودا والذين آمنوا معه برحمة منا ونجيناهم من عذاب غليظ","އަދި ތިމަންރަސްކަލާނގެ (އަޒާބުގެ) އަމުރުފުޅު އައިހިނދު، ތިމަންރަސްކަލާނގެ ހޫދުގެފާނާއި، އެކަލޭގެފާނުގެ އަރިހުގައި އީމާން ވެގެންތިބި މީހުން، ތިމަންރަސްކަލާނގެ ހަޒުރަތުން އައި ރަހުމަތަކާއެކު ސަލާމަތްކުރެއްވީމެވެ. އަދި ގަދަފަދަވެގެންވާ އަޒާބުން ތިމަންރަސްކަލާނގެ އެއުރެން ސަލާމަތް ކުރެއްވީމެވެ.","",""],["₁₁ سورة هود","59","وَتِلۡكَ عَادٞۖ جَحَدُواْ بِـَٔايَٰتِ رَبِّهِمۡ وَعَصَوۡاْ رُسُلَهُۥ وَٱتَّبَعُوٓاْ أَمۡرَ كُلِّ جَبَّارٍ عَنِيدٖ ٥٩","وتلك عاد جحدوا بآيات ربهم وعصوا رسله واتبعوا أمر كل جبار عنيد","އެއީ ޢާދު ބާގައިމީހުންނެވެ. އެއުރެންގެ ވެރިރަސްކަލާނގެ އާޔަތްތަކަށް އެއުރެން ދެކޮޅުހެދޫއެވެ. އަދި އެކަލާނގެ ރަސޫލުންނަށް އެއުރެން އުރެދުނޫއެވެ. އަދި ހަރުކަށި، ކޮންމެ ޖައްބާރު (އަނިޔާވެރި) އެއްގެ އަމުރަށް، އެއުރެން ތަބާ ވޫއެވެ.","",""],["₁₁ سورة هود","60","وَأُتۡبِعُواْ فِي هَٰذِهِ ٱلدُّنۡيَا لَعۡنَةٗ وَيَوۡمَ ٱلۡقِيَٰمَةِۗ أَلَآ إِنَّ عَادٗا كَفَرُواْ رَبَّهُمۡۗ أَلَا بُعۡدٗا لِّعَادٖ قَوۡمِ هُودٖ ٦٠","وأتبعوا في هذه الدنيا لعنة ويوم القيامة ألا إن عادا كفروا ربهم ألا بعدا لعاد قوم هود","މި ދުނިޔޭގައިވެސް، އަދި ގިޔާމަތް ދުވަހުންވެސް، އެއުރެންނަށް ލައުނަތް ލެއްވިއެވެ. ދަންނާށެވެ! ހަމަކަށަވަރުން، ޢާދު ބާގައިމީހުން، އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ކާފިރު ވޫއެވެ. ދަންނާށެވެ! ޢާދު ބާގައިމީހުންނަށް ހަލާކާއި، ގެއްލުން ހުށްޓެވެ. (އެއީ) ހޫދުގެފާނުގެ ގައުމުގެމީހުންނެވެ.","",""],["₁₁ سورة هود","61","۞وَإِلَىٰ ثَمُودَ أَخَاهُمۡ صَٰلِحٗاۚ قَالَ يَٰقَوۡمِ ٱعۡبُدُواْ ٱللَّهَ مَا لَكُم مِّنۡ إِلَٰهٍ غَيۡرُهُۥۖ هُوَ أَنشَأَكُم مِّنَ ٱلۡأَرۡضِ وَٱسۡتَعۡمَرَكُمۡ فِيهَا فَٱسۡتَغۡفِرُوهُ ثُمَّ تُوبُوٓاْ إِلَيۡهِۚ إِنَّ رَبِّي قَرِيبٞ مُّجِيبٞ ٦١","وإلى ثمود أخاهم صالحا قال يا قوم اعبدوا الله ما لكم من إله غيره هو أنشأكم من الأرض واستعمركم فيها فاستغفروه ثم توبوا إليه إن ربي قريب مجيب","އަދި ތިމަންރަސްކަލާނގެ ޘަމޫދު ބާގައިމީހުންގެ ގާތަށް އެއުރެންގެ އަޚު ޞާލިހުގެފާނު ފޮނުއްވީމެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ﷲއަށް ތިޔަބައިމީހުން އަޅުކަންކުރާށެވެ! އެކަލާނގެ ފިޔަވައި، އެހެން އިލާހަކު ތިޔަބައިމީހުންނަކަށް ނުވެއެވެ. އެކަލާނގެ ތިޔަބައިމީހުން ބިމުގެ ތެރެއިން އުފެއްދެވިއެވެ. އަދި އެ ބިމުގައި އިމާރާތް ކޮށް، އެ ބިމުގެ ފައިދާ ލިބިގަންނަ ބަޔަކު ކަމުގައި ތިޔަބައިމީހުން ލެއްވިއެވެ. ފަހެ، ތިޔަބައިމީހުން ފާފަފުއްސެވުންއެދި، އެކަލާނގެއަށް ދަންނަވާށެވެ! ދެން ތިޔަބައިމީހުން، އެކަލާނގެއަށް ތައުބާ ވާށެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ކުއްތަންވެވޮޑިގެންވާ (ދުއާ) އިޖާބަކުރައްވާ ރަސްކަލާނގެއެވެ.","",""],["₁₁ سورة هود","62","قَالُواْ يَٰصَٰلِحُ قَدۡ كُنتَ فِينَا مَرۡجُوّٗا قَبۡلَ هَٰذَآۖ أَتَنۡهَىٰنَآ أَن نَّعۡبُدَ مَا يَعۡبُدُ ءَابَآؤُنَا وَإِنَّنَا لَفِي شَكّٖ مِّمَّا تَدۡعُونَآ إِلَيۡهِ مُرِيبٖ ٦٢","قالوا يا صالح قد كنت فينا مرجوا قبل هذا أتنهانا أن نعبد ما يعبد آباؤنا وإننا لفي شك مما تدعونا إليه مريب","އެއުރެން ދެންނެވޫއެވެ. އޭ ސާލިހުގެފާނެވެ! ހަމަކަށަވަރުން، މީގެކުރިން ތިމަންމެންގެ ތެރޭގައި އެދެވިގެންވާ (މާތް) މީހެއްކަމުގައި ކަލޭގެފާނު ވީމުއެވެ. (އެހެންކަމާއެކުވެސް) ތިމަންމެންގެ ކާބަފައިން އަޅުކަންކުރާ ފަރާތްތަކަށް، އަޅުކަންކުރުން ތިމަންމެންނަށް މަނާކުރައްވަނީތޯއެވެ؟ ހަމަކަށަވަރުން، ތިމަންމެންނަށް ކަލޭގެފާނު ތިޔަ ގޮވައިލައްވާ ކަންތަކާމެދު، ތިމަންމެން މިތިބީ، ވަސްވާސްތެރިކަމުން ފުރިގެންވާ ޝައްކެއްގައިކަން ކަށަވަރެވެ.","",""],["₁₁ سورة هود","63","قَالَ يَٰقَوۡمِ أَرَءَيۡتُمۡ إِن كُنتُ عَلَىٰ بَيِّنَةٖ مِّن رَّبِّي وَءَاتَىٰنِي مِنۡهُ رَحۡمَةٗ فَمَن يَنصُرُنِي مِنَ ٱللَّهِ إِنۡ عَصَيۡتُهُۥۖ فَمَا تَزِيدُونَنِي غَيۡرَ تَخۡسِيرٖ ٦٣","قال يا قوم أرأيتم إن كنت على بينة من ربي وآتاني منه رحمة فمن ينصرني من الله إن عصيته فما تزيدونني غير تخسير","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން ނިކަން ބުނެބަލާށެވެ! އަހުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައި ފާޅުވެގެންވާ ތެދުމަގެއްގައި، އަހުރެންވީނަމަ، އަދި އެކަލާނގެ ހަޒުރަތުން އަހުރެންނަށް ރަހުމަތެއް (އެބަހީ: ނަބީކަމާއި ރަސޫލު ކަން) އެކަލާނގެ ދެއްވިހިނދު، އެކަލާނގެއަށް އަހުރެން އުރެދިއްޖެނަމަ، ﷲގެ ހަޒުރަތުން އަހުރެންނަށް ނަސްރު ދޭނީ ފަހެ، ކާކުހެއްޔެވެ؟ ފަހެ، ގެއްލުންދިނުން ނޫން އެހެންކަމެއް، ތިޔަބައިމީހުން އަހުރެންނަކަށް އިތުރެއް ނުކުރަމުއެވެ.","",""],["₁₁ سورة هود","64","وَيَٰقَوۡمِ هَٰذِهِۦ نَاقَةُ ٱللَّهِ لَكُمۡ ءَايَةٗۖ فَذَرُوهَا تَأۡكُلۡ فِيٓ أَرۡضِ ٱللَّهِۖ وَلَا تَمَسُّوهَا بِسُوٓءٖ فَيَأۡخُذَكُمۡ عَذَابٞ قَرِيبٞ ٦٤","ويا قوم هذه ناقة الله لكم آية فذروها تأكل في أرض الله ولا تمسوها بسوء فيأخذكم عذاب قريب","އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! މިއޮތީ ތިޔަބައިމީހުންނަށް ހެތްކެއްގެ ގޮތުގައި އޮތް ﷲގެ ޖަމަލެވެ. ފަހެ، ﷲގެ ބިމުގައި، އެ ޖަމަލު ކައިއުޅޭން އޭތި ދޫކޮށްލާށެވެ! އަދި އެއަށް އެއްވެސް ގޯނާއެއް ނުކުރާށެވެ! ފަހެ، (އެކަންކޮށްފިނަމަ) ގާތްވެގެންވާ އަޒާބެއް އައިސް ތިޔަބައިމީހުންނަށް ޖެހިދާނެތެވެ.","",""],["₁₁ سورة هود","65","فَعَقَرُوهَا فَقَالَ تَمَتَّعُواْ فِي دَارِكُمۡ ثَلَٰثَةَ أَيَّامٖۖ ذَٰلِكَ وَعۡدٌ غَيۡرُ مَكۡذُوبٖ ٦٥","فعقروها فقال تمتعوا في داركم ثلاثة أيام ذلك وعد غير مكذوب","ނަމަވެސް، އެއުރެން އެ ޖަމަލު މަރައިލީއެވެ. ދެން އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންގެ ގެދޮރުގައި، ތިންދުވަސްވަންދެން ތިޔަބައިމީހުން އުފާކޮށް އުޅޭށެވެ! އެއީ ދޮގުނުކުރެވޭނެ ވައުދެކެވެ.","",""],["₁₁ سورة هود","66","فَلَمَّا جَآءَ أَمۡرُنَا نَجَّيۡنَا صَٰلِحٗا وَٱلَّذِينَ ءَامَنُواْ مَعَهُۥ بِرَحۡمَةٖ مِّنَّا وَمِنۡ خِزۡيِ يَوۡمِئِذٍۚ إِنَّ رَبَّكَ هُوَ ٱلۡقَوِيُّ ٱلۡعَزِيزُ ٦٦","فلما جاء أمرنا نجينا صالحا والذين آمنوا معه برحمة منا ومن خزي يومئذ إن ربك هو القوي العزيز","ދެންފަހެ، ތިމަންރަސްކަލާނގެ (އަޒާބުގެ) އަމުރުފުޅު އައިހިނދު، ސާލިހުގެފާނާއި، އެކަލޭގެފާނުގެ އަރިހުގައި އީމާންވި މީހުން، ތިމަންރަސްކަލާނގެ ހަޒުރަތު ންލެއްވި ރަހުމަތާއެކު، އެދުވަހުގެ ނިކަމެތިކަމުން ތިމަންރަސްކަލާނގެ ސަލާމަތްކުރެއްވީމެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ބާރުވެރިވަންތަ، ގަދަފަދަވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₁₁ سورة هود","67","وَأَخَذَ ٱلَّذِينَ ظَلَمُواْ ٱلصَّيۡحَةُ فَأَصۡبَحُواْ فِي دِيَٰرِهِمۡ جَٰثِمِينَ ٦٧","وأخذ الذين ظلموا الصيحة فأصبحوا في ديارهم جاثمين","އަދި (ބިރުވެރި) އަޑުއައިސް އަނިޔާވެރިވި މީހުން ހަލާކުކުރިއެވެ. ދެން ހެނދުންވީއިރު، އެއުރެންގެ ގޯތިގެދޮރުގައި، އެއުރެން ތިބީ، ކަކޫ މައްޗަށް ތިރިވެ، މަރުވެފައެވެ.","",""],["₁₁ سورة هود","68","كَأَن لَّمۡ يَغۡنَوۡاْ فِيهَآۗ أَلَآ إِنَّ ثَمُودَاْ كَفَرُواْ رَبَّهُمۡۗ أَلَا بُعۡدٗا لِّثَمُودَ ٦٨","كأن لم يغنوا فيها ألا إن ثمود كفروا ربهم ألا بعدا لثمود","އެއުރެން އެތާ އުޅެފައި ނުވާކަހަލައެވެ. ދަންނާށެވެ! ހަމަކަށަވަރުން، ޘަމޫދު ބާގައިމީހުން، އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ކާފިރު ވޫއެވެ. ދަންނާށެވެ! ޘަމޫދު ބާގައިމީހުންނަށް ހަލާކާއި ގެއްލުން ހުށްޓެވެ.","",""],["₁₁ سورة هود","69","وَلَقَدۡ جَآءَتۡ رُسُلُنَآ إِبۡرَٰهِيمَ بِٱلۡبُشۡرَىٰ قَالُواْ سَلَٰمٗاۖ قَالَ سَلَٰمٞۖ فَمَا لَبِثَ أَن جَآءَ بِعِجۡلٍ حَنِيذٖ ٦٩","ولقد جاءت رسلنا إبراهيم بالبشرى قالوا سلاما قال سلام فما لبث أن جاء بعجل حنيذ","އަދި ހަމަކަށަވަރުން، އުފާވެރިކަމުގެ ޚަބަރާއިގެން، ތިމަންރަސްކަލާނގެ ފޮނުއްވި ރަސޫލުން (އެބަހީ: މަލާއިކަތުން) އިބްރާހީމްގެފާނުގެ އަރިހަށް ވަޑައިގަތެވެ. އެބޭކަލުން ދެންނެވޫއެވެ. ސަލާމެވެ! އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ސަލާމެވެ! ދެން ފިހެފައިވާ، ޅަ ގެރިއެއް ގެންނެވުމުގައި، އެކަލޭގެފާނު ލަސްވެވަޑައެއް ނުގަންނަވަތެވެ.","",""],["₁₁ سورة هود","70","فَلَمَّا رَءَآ أَيۡدِيَهُمۡ لَا تَصِلُ إِلَيۡهِ نَكِرَهُمۡ وَأَوۡجَسَ مِنۡهُمۡ خِيفَةٗۚ قَالُواْ لَا تَخَفۡ إِنَّآ أُرۡسِلۡنَآ إِلَىٰ قَوۡمِ لُوطٖ ٧٠","فلما رأى أيديهم لا تصل إليه نكرهم وأوجس منهم خيفة قالوا لا تخف إنا أرسلنا إلى قوم لوط","ފަހެ، އެބޭކަލުންގެ އަތްޕުޅުތައް، އެ ފަރީއްކޮޅާ ހަމަޔަށް ނުދާތީ ދެކެވަޑައިގެން، އެބޭކަލުންނާމެދު އިންކާރުކުރެއްވިއެވެ. އަދި އެބޭކަލުންނާމެދު ހިތްޕުޅުގައި ބިރުވެރި ކަމެއް އުފެދުނެވެ. އެބޭކަލުން ދެންނެވޫއެވެ. ކަލޭގެފާނު ބިރުފުޅުގެން ވަޑައިނުގަންނަވާށެވެ! ހަމަކަށަވަރުން، ތިމަންމެން ފޮނުއްވީ، ލޫޠުގެފާނުގެ ގައުމަށެވެ.","",""],["₁₁ سورة هود","71","وَٱمۡرَأَتُهُۥ قَآئِمَةٞ فَضَحِكَتۡ فَبَشَّرۡنَٰهَا بِإِسۡحَٰقَ وَمِن وَرَآءِ إِسۡحَٰقَ يَعۡقُوبَ ٧١","وامرأته قائمة فضحكت فبشرناها بإسحاق ومن وراء إسحاق يعقوب","އަދި އެކަލޭގެފާނުގެ އަނބިކަނބަލުން (އެ ހިނދު އެތާނގައި) ހުންނެވިއެވެ. ދެން (އެބޭކަލުން އެހެން ވިދާޅުވުމުން، އެކަމާ އުފާފުޅުވެގެން) އެކަމަނާ ހިނިފުޅުވެޑުވިއެވެ. ފަހެ، އެކަމަނާއަށް އިސްޙާގުގެފާނު ލިބިވަޑައިގަންނަވާނެކަމާއި، އިސްޙާގުގެފާނުގެ ފަހަތްޕުޅުން ޔައުގޫބުގެފާނު ލިބިވަޑައިގަންނަވާނެކަމުގެ އުފާވެރި ޚަބަރު، ތިމަންރަސްކަލާނގެ އެކަމަނާއަށް ދެއްވީމެވެ.","",""],["₁₁ سورة هود","72","قَالَتۡ يَٰوَيۡلَتَىٰٓ ءَأَلِدُ وَأَنَا۠ عَجُوزٞ وَهَٰذَا بَعۡلِي شَيۡخًاۖ إِنَّ هَٰذَا لَشَيۡءٌ عَجِيبٞ ٧٢","قالت يا ويلتى أألد وأنا عجوز وهذا بعلي شيخا إن هذا لشيء عجيب","އެކަމަނާ ވިދާޅުވިއެވެ. އޭހުރި އަޖާއިބެއްގެ ބޮޑުކަމާއެވެ! ތިމަންނާ މުސްކުޅިޔަކު ކަމުގައިވާއިރުވެސް، ތިމަން ވިހާނޭ ހެއްޔެވެ؟ އަދި ތިމަންގެ ފިރިކަލުން މިހުންނެވީ މުސްކުޅިވެފައެވެ. ހަމަކަށަވަރުން، މިއީ އަޖާއިބު ވެގެންވާ ކަމެކެވެ.","",""],["₁₁ سورة هود","73","قَالُوٓاْ أَتَعۡجَبِينَ مِنۡ أَمۡرِ ٱللَّهِۖ رَحۡمَتُ ٱللَّهِ وَبَرَكَٰتُهُۥ عَلَيۡكُمۡ أَهۡلَ ٱلۡبَيۡتِۚ إِنَّهُۥ حَمِيدٞ مَّجِيدٞ ٧٣","قالوا أتعجبين من أمر الله رحمت الله وبركاته عليكم أهل البيت إنه حميد مجيد","އެބޭކަލުން ދެންނެވޫއެވެ. ﷲގެ އަމުރު ފުޅާމެދު، ކަމަނާ އަޖާއިބުވެ ވަޑައިގަންނަވަނީތޯއެވެ؟ ގޭގެ އަހުލުވެރިންނޭވެ! ތިޔަބޭކަލުންގެ މައްޗަށް ﷲގެ ރަހުމަތާއި، އެކަލާނގެ ބަރަކާތް ހުށްޓެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ ހަމްދު ލިބިވޮޑިގެންވާ، މާތް، ދީލަތިވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₁₁ سورة هود","74","فَلَمَّا ذَهَبَ عَنۡ إِبۡرَٰهِيمَ ٱلرَّوۡعُ وَجَآءَتۡهُ ٱلۡبُشۡرَىٰ يُجَٰدِلُنَا فِي قَوۡمِ لُوطٍ ٧٤","فلما ذهب عن إبراهيم الروع وجاءته البشرى يجادلنا في قوم لوط","ފަހެ، އިބްރާހީމްގެފާނުންގެ ކިބަފުޅުން ބިރުފިލައިގޮސް، އެކަލޭގެފާނަށް އުފާވެރި ޚަބަރު އައިހިނދު، ލޫޠުގެފާނުގެ ގައުމުގެމީހުންނާމެދު، އެކަލޭގެފާނު ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ސުވާލު ދަންނަވަން ފެށްޓެވިއެވެ.","",""],["₁₁ سورة هود","75","إِنَّ إِبۡرَٰهِيمَ لَحَلِيمٌ أَوَّـٰهٞ مُّنِيبٞ ٧٥","إن إبراهيم لحليم أواه منيب","ހަމަކަށަވަރުން، އިބްރާހީމްގެފާނީ، ކޯފާ މަޑު، ދުއާކުރެއްވުންގިނަ، ﷲގެ ހަޒުރަތަށް ރުޖޫއަވެ، ތައުބާ ވެވަޑައިގަންނަވާ ބޭކަލެކެވެ.","",""],["₁₁ سورة هود","76","يَـٰٓإِبۡرَٰهِيمُ أَعۡرِضۡ عَنۡ هَٰذَآۖ إِنَّهُۥ قَدۡ جَآءَ أَمۡرُ رَبِّكَۖ وَإِنَّهُمۡ ءَاتِيهِمۡ عَذَابٌ غَيۡرُ مَرۡدُودٖ ٧٦","يا إبراهيم أعرض عن هذا إنه قد جاء أمر ربك وإنهم آتيهم عذاب غير مردود","އޭ އިބްރާހީމްގެފާނެވެ! ތިޔަކަންތައް (އެބަހީ: ލޫޠުގެފާނުގެ ގައުމުގެމީހުންނާމެދު ދެންނެވުން) ދޫކޮށްލައްވާށެވެ! އެހެނީ، ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އަމުރުފުޅު އަތުވެއްޖެއެވެ. އަދި ހަމަކަށަވަރުން، އަނބުރާ ރައްދުނުކުރައްވާނޭ އަޒާބެއް، އެއުރެންގެ ގާތަށް އަންނާނެތެވެ.","",""],["₁₁ سورة هود","77","وَلَمَّا جَآءَتۡ رُسُلُنَا لُوطٗا سِيٓءَ بِهِمۡ وَضَاقَ بِهِمۡ ذَرۡعٗا وَقَالَ هَٰذَا يَوۡمٌ عَصِيبٞ ٧٧","ولما جاءت رسلنا لوطا سيء بهم وضاق بهم ذرعا وقال هذا يوم عصيب","އަދި ތިމަންރަސްކަލާނގެ ރަސޫލުން (އެބަހީ: މަލާއިކަތުން) ލޫޠުގެފާނުގެ އަރިހަށް ވަޑައިގަތްހިނދު (ގައުމުގެމީހުންގެ ފާސިދުކަމުގެ ސަބަބުން، އެބޭކަލުންނަށް ދެރަގޮތެއް ވެދާނެތީ) އެބޭކަލުންނާމެދު ދެރަފުޅުވެ ހިތާމަކުރެއްވިއެވެ. އަދި އެބޭކަލުންނާމެދު ހިތްޕުޅު ދަތިވިއެވެ. އަދި ވިދާޅުވިއެވެ. މިއީ ވަރަށް ހިތާމަވެރި ދުވަހެކެވެ.","",""],["₁₁ سورة هود","78","وَجَآءَهُۥ قَوۡمُهُۥ يُهۡرَعُونَ إِلَيۡهِ وَمِن قَبۡلُ كَانُواْ يَعۡمَلُونَ ٱلسَّيِّـَٔاتِۚ قَالَ يَٰقَوۡمِ هَـٰٓؤُلَآءِ بَنَاتِي هُنَّ أَطۡهَرُ لَكُمۡۖ فَٱتَّقُواْ ٱللَّهَ وَلَا تُخۡزُونِ فِي ضَيۡفِيٓۖ أَلَيۡسَ مِنكُمۡ رَجُلٞ رَّشِيدٞ ٧٨","وجاءه قومه يهرعون إليه ومن قبل كانوا يعملون السيئات قال يا قوم هؤلاء بناتي هن أطهر لكم فاتقوا الله ولا تخزون في ضيفي أليس منكم رجل رشيد","އަދި އެކަލޭގެފާނުގެ ގައުމުގެމީހުން އެކަލޭގެފާނުގެ އަރިހަށް އަވަސް އަވަހަށް އައޫއެވެ. ކުރިން އެއުރެންނަކީ، ނުބައި (ފާޙީޝް) ކަންތައްތައް ކޮށްއުޅުނު މީހުންނެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! މިތިބީ އަހުރެންގެ (އެބަހީ: ގައުމުގެ) އަންހެން ދަރިންނެވެ. (ތިޔަބައިމީހުން ޝަރުއީ ގޮތުން އެކަނބަލުންނާ ކާވެނިކުރާނަމަ) އެކަނބަލުން ތިޔަބައިމީހުންނަށްޓަކައި ސާފުކަން ބޮޑެވެ. ފަހެ، ތިޔަބައިމީހުން، ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ތިމަންކަލޭގެފާނުގެ މެހުމާނުންގެ ކުރިމަތީގައި، ތިމަންކަލޭގެފާނު ލަދުވެތި ނުކުރާށެވެ! ތިޔަބައިމީހުންގެ ތެރޭގައި ހޭޖެހޭ ފިރިހެނަކު ނުވަނީހެއްޔެވެ؟","",""],["₁₁ سورة هود","79","قَالُواْ لَقَدۡ عَلِمۡتَ مَا لَنَا فِي بَنَاتِكَ مِنۡ حَقّٖ وَإِنَّكَ لَتَعۡلَمُ مَا نُرِيدُ ٧٩","قالوا لقد علمت ما لنا في بناتك من حق وإنك لتعلم ما نريد","އެއުރެން ދެންނެވޫއެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ އަންހެން ދަރިންނާމެދު އެއްވެސް ހައްގެއް (އެބަހީ: އެއްވެސް ބޭނުމެއް) ތިމަންމެންނަށް ނުވާކަން ކަލޭގެފާނަށް އެނގިވަޑައިގަންނަވާނެތެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންމެން އެދޭ ކަންތައް ކަލޭގެފާނަށް ރަނގަޅަށް އެނގިވަޑައިގަންނަވާނެތެވެ.","",""],["₁₁ سورة هود","80","قَالَ لَوۡ أَنَّ لِي بِكُمۡ قُوَّةً أَوۡ ءَاوِيٓ إِلَىٰ رُكۡنٖ شَدِيدٖ ٨٠","قال لو أن لي بكم قوة أو آوي إلى ركن شديد","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންނާމެދު، ތިމަންކަލޭގެފާނަށް ބާރެއް ލިބިވަޑައިގެންފައިވާނަމައެވެ! ނުވަތަ ބާރުގަދަ ފަރާތަކަށް ދެވޭނެނަމައެވެ!","",""],["₁₁ سورة هود","81","قَالُواْ يَٰلُوطُ إِنَّا رُسُلُ رَبِّكَ لَن يَصِلُوٓاْ إِلَيۡكَۖ فَأَسۡرِ بِأَهۡلِكَ بِقِطۡعٖ مِّنَ ٱلَّيۡلِ وَلَا يَلۡتَفِتۡ مِنكُمۡ أَحَدٌ إِلَّا ٱمۡرَأَتَكَۖ إِنَّهُۥ مُصِيبُهَا مَآ أَصَابَهُمۡۚ إِنَّ مَوۡعِدَهُمُ ٱلصُّبۡحُۚ أَلَيۡسَ ٱلصُّبۡحُ بِقَرِيبٖ ٨١","قالوا يا لوط إنا رسل ربك لن يصلوا إليك فأسر بأهلك بقطع من الليل ولا يلتفت منكم أحد إلا امرأتك إنه مصيبها ما أصابهم إن موعدهم الصبح أليس الصبح بقريب","އެބޭކަލުން ދެންނެވޫއެވެ. އޭ ލޫޠުގެފާނެވެ! ހަމަކަށަވަރުން، ތިމަންމެންނީ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ފޮނުއްވި ބޭކަލުންނީމުއެވެ. ކަލޭގެފާނާ ހަމަޔަށް އެއުރެންނަކަށް ވާޞިލެއް ނުވެވޭނެތެވެ. ފަހެ، ރޭގަނޑުން ބައެއްގައި ކަލޭގެފާނުގެ އަހުލުވެރިންނާއެކު، ނުކުމެވަޑައިގެން ހިންގަވާށެވެ! އަދި ތިޔައިގެ ތެރެއިން އެކަކުވެސް، ކަލޭގެފާނުގެ އަނބިކަނބަލުން ފިޔަވައި އެނބުރި ފަސްނުބަލާށެވެ! ހަމަކަށަވަރުން، އެއުރެންނަށް (އެބަހީ: އެ ކާފިރުންނަށް) ޖެހޭކަމެއް އެކަނބުލޭގެއަށްވެސް ޖެހޭނެތެވެ. ހަމަކަށަވަރުން، އެއުރެންނަށް ކަނޑައެޅިގެންވާ ވަގުތަކީ ހެނދުނު ފަތިހެވެ. ފަތިސް ވަގުތު، ގާތުގައި ނުވޭހެއްޔެވެ؟","",""],["₁₁ سورة هود","82","فَلَمَّا جَآءَ أَمۡرُنَا جَعَلۡنَا عَٰلِيَهَا سَافِلَهَا وَأَمۡطَرۡنَا عَلَيۡهَا حِجَارَةٗ مِّن سِجِّيلٖ مَّنضُودٖ ٨٢","فلما جاء أمرنا جعلنا عاليها سافلها وأمطرنا عليها حجارة من سجيل منضود","ދެން ފަހެ، ތިމަންރަސްކަލާނގެ (އަޒާބުގެ) އަމުރުފުޅު އައިހިނދު، އެ ރަށުގެ މައްޗަށް އޮތްފުށް ދަށަށް ޖެއްސެވީމެވެ. އަދި އަލިފާނުން ދޮންކުރައްވާފައިވާ، މަށީގެ ހިލައިން ތިމަންރަސްކަލާނގެ އެ ރަށަށް ވާރޭ ވެއްސެވީމެވެ.","",""],["₁₁ سورة هود","83","مُّسَوَّمَةً عِندَ رَبِّكَۖ وَمَا هِيَ مِنَ ٱلظَّـٰلِمِينَ بِبَعِيدٖ ٨٣","مسومة عند ربك وما هي من الظالمين ببعيد","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ފާހަގަކުރައްވާފައިވާ ގޮތުގައެވެ. އަދި އަނިޔާވެރިންނާ ދުރުގައިވާ ކަމެއް ކަމުގައި އެކަންތައް ނުވެތެވެ.","",""],["₁₁ سورة هود","84","۞وَإِلَىٰ مَدۡيَنَ أَخَاهُمۡ شُعَيۡبٗاۚ قَالَ يَٰقَوۡمِ ٱعۡبُدُواْ ٱللَّهَ مَا لَكُم مِّنۡ إِلَٰهٍ غَيۡرُهُۥۖ وَلَا تَنقُصُواْ ٱلۡمِكۡيَالَ وَٱلۡمِيزَانَۖ إِنِّيٓ أَرَىٰكُم بِخَيۡرٖ وَإِنِّيٓ أَخَافُ عَلَيۡكُمۡ عَذَابَ يَوۡمٖ مُّحِيطٖ ٨٤","وإلى مدين أخاهم شعيبا قال يا قوم اعبدوا الله ما لكم من إله غيره ولا تنقصوا المكيال والميزان إني أراكم بخير وإني أخاف عليكم عذاب يوم محيط","އަދި މަދިޔަނުގެމީހުންގެ ގާތަށް ތިމަންރަސްކަލާނގެ، އެއުރެންގެ އަޚު، ޝުއައިބުގެފާނު ފޮނުއްވީމެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން ﷲއަށް އަޅުކަންކުރާށެވެ! އެކަލާނގެ ފިޔަވައި އެހެން އިލާހަކު ތިޔަބައިމީހުންނަކަށް ނުވެއެވެ. އަދި މިނުމުގައްޔާއި، ކިރުމުގައި، ތިޔަބައިމީހުން އުނިނުކުރާށެވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުންވަނީ (ފުދި) ހެޔޮޙާލުގައި ކަމަށް ތިމަންކަލޭގެފާނަށް ފެނިވަޑައިގަނެއެވެ. އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ވަށާލައިފައިވާ ދުވަހެއްގެ އަޒާބަށް، ތިޔަބައިމީހުންނާމެދު، ތިމަންކަލޭގެފާނު ބިރުފުޅު ގަނެތެވެ.","",""],["₁₁ سورة هود","85","وَيَٰقَوۡمِ أَوۡفُواْ ٱلۡمِكۡيَالَ وَٱلۡمِيزَانَ بِٱلۡقِسۡطِۖ وَلَا تَبۡخَسُواْ ٱلنَّاسَ أَشۡيَآءَهُمۡ وَلَا تَعۡثَوۡاْ فِي ٱلۡأَرۡضِ مُفۡسِدِينَ ٨٥","ويا قوم أوفوا المكيال والميزان بالقسط ولا تبخسوا الناس أشياءهم ولا تعثوا في الأرض مفسدين","އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން މިނުމާއި، ކިރުން، ޢަދުލަށް ފުރިހަމަކުރާށެވެ! އަދި މީސްތަކުންނަށް އެއުރެންގެ ތަކެތި އުނިނުކުރާށެވެ! އަދި ފާސިދުން ކަމުގައިވެތިބެ ތިޔަބައިމީހުން ބިމުގައި ފަސާދަ ނުކުރާހުށިކަމެވެ!","",""],["₁₁ سورة هود","86","بَقِيَّتُ ٱللَّهِ خَيۡرٞ لَّكُمۡ إِن كُنتُم مُّؤۡمِنِينَۚ وَمَآ أَنَا۠ عَلَيۡكُم بِحَفِيظٖ ٨٦","بقيت الله خير لكم إن كنتم مؤمنين وما أنا عليكم بحفيظ","ﷲ، ތިޔަބައިމީހުންނަށްޓަކައި، ދޫކުރައްވާފައިވާ އެއްޗެއް ތިޔަބައިމީހުންނަށް ހެޔޮކަން ބޮޑެވެ. ތިޔަބައިމީހުންނީ، މުއުމިނުން ކަމުގައިވާނަމައެވެ. އަދި ތިޔަބައިމީހުންގެ މައްޗަށް ހުރި ފާރަވެރިއަކު ކަމުގައި، ތިމަންކަލޭގެފާނު ނުވަމެވެ.","",""],["₁₁ سورة هود","87","قَالُواْ يَٰشُعَيۡبُ أَصَلَوٰتُكَ تَأۡمُرُكَ أَن نَّتۡرُكَ مَا يَعۡبُدُ ءَابَآؤُنَآ أَوۡ أَن نَّفۡعَلَ فِيٓ أَمۡوَٰلِنَا مَا نَشَـٰٓؤُاْۖ إِنَّكَ لَأَنتَ ٱلۡحَلِيمُ ٱلرَّشِيدُ ٨٧","قالوا يا شعيب أصلاتك تأمرك أن نترك ما يعبد آباؤنا أو أن نفعل في أموالنا ما نشاء إنك لأنت الحليم الرشيد","އެއުރެން ދެންނެވޫއެވެ. އޭ ޝުއައިބުގެފާނެވެ! ތިމަންމެންގެ ކާބަފައިން އަޅުކަންކޮށް އުޅުނު ތަކެތި ދޫކޮށްލުމަށް، ނުވަތަ ތިމަންމެންގެ މުދާތަކާމެދު ތިމަންމެން އެދޭގޮތަކަށް ކަންތައްކުރުން ދޫކޮށްލުމަށް، ކަލޭގެފާނުގެ ނަމާދު، ކަލޭގެފާނަށް އަމުރުކުރަނީތޯއެވެ! ހަމަކަށަވަރުން، ކަލޭގެފާނީ ކެތްތެރި، ވިސްނުންފުޅު ފުރިހަމަ ބޭކަލަކީމުއެވެ. (ނޯޓު: އެއުރެން މިގޮތަށް ދެންނެވީ، މަލާމާތެއްގެ ގޮތުގައިކަމަށް މުފައްސިރުން ލިޔުއްވާފައިވެއެވެ.)","",""],["₁₁ سورة هود","88","قَالَ يَٰقَوۡمِ أَرَءَيۡتُمۡ إِن كُنتُ عَلَىٰ بَيِّنَةٖ مِّن رَّبِّي وَرَزَقَنِي مِنۡهُ رِزۡقًا حَسَنٗاۚ وَمَآ أُرِيدُ أَنۡ أُخَالِفَكُمۡ إِلَىٰ مَآ أَنۡهَىٰكُمۡ عَنۡهُۚ إِنۡ أُرِيدُ إِلَّا ٱلۡإِصۡلَٰحَ مَا ٱسۡتَطَعۡتُۚ وَمَا تَوۡفِيقِيٓ إِلَّا بِٱللَّهِۚ عَلَيۡهِ تَوَكَّلۡتُ وَإِلَيۡهِ أُنِيبُ ٨٨","قال يا قوم أرأيتم إن كنت على بينة من ربي ورزقني منه رزقا حسنا وما أريد أن أخالفكم إلى ما أنهاكم عنه إن أريد إلا الإصلاح ما استطعت وما توفيقي إلا بالله عليه توكلت وإليه أنيب","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން ނިކަން ބުނެބަލާށެވެ! އަހުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައި ފާޅުވެގެންވާ ތެދުމަގެއްގައި އަހުރެންވީނަމަ، އަދި އެކަލާނގެ ހަޒުރަތުން ހެޔޮވެގެންވާ ރިޒްގު ދެއްވި ހިނދު (އެކަމަށް ފުރަގަސްދެވޭނެހެއްޔެވެ؟) އަދި އަހުރެން ތިޔަބައިމީހުންނަށް ނަހީކުރާ ކަންތައް އަހުރެން ކުރާކަށް ބޭނުމެއް ނުވެތެވެ. އަހުރެންނަށް ކުޅަދާނަވީވަރަކަށް، އިސްލާހުކުރުން މެނުވީ، އަހުރެން ބޭނުމެއް ނުވެތެވެ. އަދި ﷲގެ ހަޒުރަތުން މެނުވީ، އަހުރެންނަށް ތައުފީގު ލިބުމެއްނުވެތެވެ. އަހުރެން ވަކީލުކުރަނީ، އެކަލާނގެއަށެވެ. އަދި ތައުބާ ވަނީވެސް، އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["₁₁ سورة هود","89","وَيَٰقَوۡمِ لَا يَجۡرِمَنَّكُمۡ شِقَاقِيٓ أَن يُصِيبَكُم مِّثۡلُ مَآ أَصَابَ قَوۡمَ نُوحٍ أَوۡ قَوۡمَ هُودٍ أَوۡ قَوۡمَ صَٰلِحٖۚ وَمَا قَوۡمُ لُوطٖ مِّنكُم بِبَعِيدٖ ٨٩","ويا قوم لا يجرمنكم شقاقي أن يصيبكم مثل ما أصاب قوم نوح أو قوم هود أو قوم صالح وما قوم لوط منكم ببعيد","އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! އަހުރެންނާ ދެކޮޅުވެރިވުން އެއީ، ތިޔަބައިމީހުންނަށް މުސީބަތް ޖެހޭކަމަކަށް ނުހަދާހުށިކަމެވެ! (އެއީ) ނޫޙުގެފާނުގެ ގައުމުގެމީހުންނަށް، ނުވަތަ ހޫދުގެފާނުގެ ގައުމުގެމީހުންނަށް، ނުވަތަ ސާލިހުގެފާނުގެ ގައުމުގެމީހުންނަށް ޖެހުނުފަދަ މުސީބަތެކެވެ. ލޫޠުގެފާނުގެ ގައުމުގެމީހުން (ހަލާކުވެދިޔަ ދުވަސް) ތިޔަބައިމީހުންނާ ދުރެއްގައެއް ނުވެއެވެ.","",""],["₁₁ سورة هود","90","وَٱسۡتَغۡفِرُواْ رَبَّكُمۡ ثُمَّ تُوبُوٓاْ إِلَيۡهِۚ إِنَّ رَبِّي رَحِيمٞ وَدُودٞ ٩٠","واستغفروا ربكم ثم توبوا إليه إن ربي رحيم ودود","އަދި ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ފާފަފުއްސެވުންއެދި، ތިޔަބައިމީހުން ދަންނަވާށެވެ! ދެން ތިޔަބައިމީހުން އެކަލާނގެއަށް ތައުބާ ވާށެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ ރަޙީމްވަންތަ ނުހަނު އޯގާވަންތަ ރަސްކަލާނގެއެވެ.","",""],["₁₁ سورة هود","91","قَالُواْ يَٰشُعَيۡبُ مَا نَفۡقَهُ كَثِيرٗا مِّمَّا تَقُولُ وَإِنَّا لَنَرَىٰكَ فِينَا ضَعِيفٗاۖ وَلَوۡلَا رَهۡطُكَ لَرَجَمۡنَٰكَۖ وَمَآ أَنتَ عَلَيۡنَا بِعَزِيزٖ ٩١","قالوا يا شعيب ما نفقه كثيرا مما تقول وإنا لنراك فينا ضعيفا ولولا رهطك لرجمناك وما أنت علينا بعزيز","އެއުރެން ދެންނެވޫއެވެ. އޭ ޝުއައިބުގެފާނެވެ! ކަލޭގެފާނު ވިދާޅުވާ އެއްޗެހީގެ ތެރެއިން ގިނައެއްޗެހި، ތިމަންމެންނަކަށް ނުވިސްނެތެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންމެން ދެކެނީ، ކަލޭގެފާނަކީ ތިމަންމެންގެ ތެރޭގައިވާ ނިކަމެއްޗެއް ކަމަށެވެ. އަދި ކަލޭގެފާނުގެ ގާތްތިމާގެ މީސްކޮޅު ނުވާނަމަ، ތިމަންމެން ހަމަކަށަވަރުންވެސް، ކަލޭގެފާނު ރަޖަމްކުޅައީމުހެވެ. އަދި ކަލޭގެފާނަކީ، ތިމަންމެންގެ މައްޗަށް ހުންނެވި ޢިއްޒަތް ތެރިޔަކީމުއެއް ނޫނެވެ.","",""],["₁₁ سورة هود","92","قَالَ يَٰقَوۡمِ أَرَهۡطِيٓ أَعَزُّ عَلَيۡكُم مِّنَ ٱللَّهِ وَٱتَّخَذۡتُمُوهُ وَرَآءَكُمۡ ظِهۡرِيًّاۖ إِنَّ رَبِّي بِمَا تَعۡمَلُونَ مُحِيطٞ ٩٢","قال يا قوم أرهطي أعز عليكم من الله واتخذتموه وراءكم ظهريا إن ربي بما تعملون محيط","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ﷲއަށްވުރެވެސް ބޮޑަށް، ތިޔަބައިމީހުންގެ މައްޗަށް ޢިއްޒަތް ތެރިވެގެންވަނީ އަހުރެންގެ ގާތްތިމާގެ މީސްކޮޅު ހެއްޔެވެ؟ އަދި އެކަލާނގެއީ، ތިޔަބައިމީހުންގެ ފުރަގަހަށް ދޫކޮށްފައިވާ ފަރާތެއްކަމުގައި ތިޔަބައިމީހުން ހަދައިފީމުއެވެ. ހަމަކަށަވަރުން، އަހުރެންގެ ވެރިރަސްކަލާނގެއީ، ތިޔަބައިމީހުންކުރާ ކަންތައް ފުރިހަމައަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₁₁ سورة هود","93","وَيَٰقَوۡمِ ٱعۡمَلُواْ عَلَىٰ مَكَانَتِكُمۡ إِنِّي عَٰمِلٞۖ سَوۡفَ تَعۡلَمُونَ مَن يَأۡتِيهِ عَذَابٞ يُخۡزِيهِ وَمَنۡ هُوَ كَٰذِبٞۖ وَٱرۡتَقِبُوٓاْ إِنِّي مَعَكُمۡ رَقِيبٞ ٩٣","ويا قوم اعملوا على مكانتكم إني عامل سوف تعلمون من يأتيه عذاب يخزيه ومن هو كاذب وارتقبوا إني معكم رقيب","އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުންގެ ގޮތުގައި ތިބެގެން ތިޔަބައިމީހުން ޢަމަލު ކޮށްބަލާށެވެ! ހަމަކަށަވަރުން، އަހުރެންވެސް (އަހުރެންގެ ގޮތުގައި) ޢަމަލުކުރާހުށީމެވެ. އެމީހަކު ނިކަމެތި ކުރަނިވި އަޒާބެއް، އެމީހަކާ ހަމަޔަށް އަންނަ މީހަކީ، ކާކުކަމާއި، ދޮގުހަދާ މީހަކީ ކާކުކަން، ނިކަންހުރެ ތިޔަބައިމީހުންނަށް އެނގޭނެތެވެ. އަދި ތިޔަބައިމީހުން ބަލަބަލާ ތިބޭށެވެ! ހަމަކަށަވަރުން، އަހުރެންވެސް ތިޔަބައިމީހުންނާއެކު ބަލަބަލާ އެބަހުރީމެވެ.","",""],["₁₁ سورة هود","94","وَلَمَّا جَآءَ أَمۡرُنَا نَجَّيۡنَا شُعَيۡبٗا وَٱلَّذِينَ ءَامَنُواْ مَعَهُۥ بِرَحۡمَةٖ مِّنَّا وَأَخَذَتِ ٱلَّذِينَ ظَلَمُواْ ٱلصَّيۡحَةُ فَأَصۡبَحُواْ فِي دِيَٰرِهِمۡ جَٰثِمِينَ ٩٤","ولما جاء أمرنا نجينا شعيبا والذين آمنوا معه برحمة منا وأخذت الذين ظلموا الصيحة فأصبحوا في ديارهم جاثمين","އަދި ތިމަންރަސްކަލާނގެ (އަޒާބުގެ) އަމުރުފުޅު އައިހިނދު، ޝުއައިބުގެފާނާއި، އެކަލޭގެފާނުގެ އަރިހުގައި އީމާން ވެގެންތިބި މީހުން، ތިމަންރަސްކަލާނގެ ރަހުމަތްފުޅުން ސަލާމަތްކުރެއްވީމެވެ. އަދި (ބިރުވެރި) އަޑުއައިސް، އަނިޔާވެރިވީ މީހުން ހަލާކު ކުރިއެވެ. ދެން ހެނދުންވީއިރު، އެއުރެންގެ ގޯތި ގެދޮރުގައި އެއުރެންތިބީ، ކަކޫމައްޗަށް ތިރިވެ، މަރުވެފައެވެ.","",""],["₁₁ سورة هود","95","كَأَن لَّمۡ يَغۡنَوۡاْ فِيهَآۗ أَلَا بُعۡدٗا لِّمَدۡيَنَ كَمَا بَعِدَتۡ ثَمُودُ ٩٥","كأن لم يغنوا فيها ألا بعدا لمدين كما بعدت ثمود","އެއުރެން އެތާ އުޅެފައި ނުވާކަހަލައެވެ. ދަންނާށެވެ! ޘަމޫދު ބާގައި މީހުންވެސް ހަލާކުވެ ނެތިދިޔަފަދައިން، މަދިޔަނުގެމީހުންނަށް ހަލާކާއި ގެއްލުން ހުށްޓެވެ.","",""],["₁₁ سورة هود","96","وَلَقَدۡ أَرۡسَلۡنَا مُوسَىٰ بِـَٔايَٰتِنَا وَسُلۡطَٰنٖ مُّبِينٍ ٩٦","ولقد أرسلنا موسى بآياتنا وسلطان مبين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާއި، ބަޔާންވެގެންވާ ހުއްޖަތަކާއެކު، މޫސާގެފާނު ފޮނުއްވީމެވެ.","",""],["₁₁ سورة هود","97","إِلَىٰ فِرۡعَوۡنَ وَمَلَإِيْهِۦ فَٱتَّبَعُوٓاْ أَمۡرَ فِرۡعَوۡنَۖ وَمَآ أَمۡرُ فِرۡعَوۡنَ بِرَشِيدٖ ٩٧","إلى فرعون وملئه فاتبعوا أمر فرعون وما أمر فرعون برشيد","ފިރްޢައުނާއި، އޭނާގެ ބޮޑުންގެ ގާތަށެވެ. ފަހެ، އެއުރެން ފިރްޢައުނުގެ އަމުރަށް ތަބާ ވޫއެވެ. ފިރްޢައުނުގެ އަމުރު ހެޔޮލަފާ އަމުރެއްކަމުގައި ނުވެތެވެ.","",""],["₁₁ سورة هود","98","يَقۡدُمُ قَوۡمَهُۥ يَوۡمَ ٱلۡقِيَٰمَةِ فَأَوۡرَدَهُمُ ٱلنَّارَۖ وَبِئۡسَ ٱلۡوِرۡدُ ٱلۡمَوۡرُودُ ٩٨","يقدم قومه يوم القيامة فأوردهم النار وبئس الورد المورود","ގިޔާމަތް ދުވަހުން، އޭނާގެ ގައުމުގެމީހުންގެ ކުރީގައިހުރެ، އެއުރެން ނަރަކައަށް ގެންގޮސް ވައްދާނެތެވެ. (އެއުރެންނަށް) ވަދެވޭތަނުގެ ހުރި ނުބައިކަމާއެވެ!","",""],["₁₁ سورة هود","99","وَأُتۡبِعُواْ فِي هَٰذِهِۦ لَعۡنَةٗ وَيَوۡمَ ٱلۡقِيَٰمَةِۚ بِئۡسَ ٱلرِّفۡدُ ٱلۡمَرۡفُودُ ٩٩","وأتبعوا في هذه لعنة ويوم القيامة بئس الرفد المرفود","މި ދުނިޔެމަތީގައި އެއުރެންނަށް ލައުނަތް ލެއްވިއެވެ. އަދި ގިޔާމަތް ދުވަހުންވެސް މެއެވެ. (އެއުރެންނަށް) ދެއްވާނެ އެއްޗެއްގެ ހުރި ނުބައިކަމާއެވެ!","",""],["₁₁ سورة هود","100","ذَٰلِكَ مِنۡ أَنۢبَآءِ ٱلۡقُرَىٰ نَقُصُّهُۥ عَلَيۡكَۖ مِنۡهَا قَآئِمٞ وَحَصِيدٞ ١٠٠","ذلك من أنباء القرى نقصه عليك منها قائم وحصيد","އެއީ ރަށްތަކުގެ ޚަބަރުތަކުގެ ތެރެއިން ބަޔެކެވެ. ތިމަންރަސްކަލާނގެ އެ ޚަބަރުތައް ކަލޭގެފާނަށް ކިޔައިދެއްވަމެވެ. ގާއިމު ވެހުރި ރަށްތަކާއި، ނެތި ހަލާކުވެގެންދިޔަ ރަށްތައް އޭގެތެރެއިންވެއެވެ.","",""],["₁₁ سورة هود","101","وَمَا ظَلَمۡنَٰهُمۡ وَلَٰكِن ظَلَمُوٓاْ أَنفُسَهُمۡۖ فَمَآ أَغۡنَتۡ عَنۡهُمۡ ءَالِهَتُهُمُ ٱلَّتِي يَدۡعُونَ مِن دُونِ ٱللَّهِ مِن شَيۡءٖ لَّمَّا جَآءَ أَمۡرُ رَبِّكَۖ وَمَا زَادُوهُمۡ غَيۡرَ تَتۡبِيبٖ ١٠١","وما ظلمناهم ولكن ظلموا أنفسهم فما أغنت عنهم آلهتهم التي يدعون من دون الله من شيء لما جاء أمر ربك وما زادوهم غير تتبيب","އަދި ތިމަންރަސްކަލާނގެ އެއުރެންނަކަށް އަނިޔާއެއް ނުކުރައްވަމެވެ. އެހެނެއްކަމަކު، އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް، އެއުރެން އަނިޔާވެރިވޫއެވެ. ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އަމުރުފުޅު އައިހިނދު، ﷲ ފިޔަވައި، އެއުރެން އަޅުކަންކޮށްއުޅުނު އެއުރެންގެ އިލާހު ންތައް، އެއްވެސްކަމެއް އެއުރެންނަކަށް ފުއްދައެއް ނުދެތެވެ. އެ އިލާހުން، އެއުރެންނަށް ގެއްލުންދިނުން މެނުވީ އިތުރެއް ނުކުރެތެވެ.","",""],["₁₁ سورة هود","102","وَكَذَٰلِكَ أَخۡذُ رَبِّكَ إِذَآ أَخَذَ ٱلۡقُرَىٰ وَهِيَ ظَٰلِمَةٌۚ إِنَّ أَخۡذَهُۥٓ أَلِيمٞ شَدِيدٌ ١٠٢","وكذلك أخذ ربك إذا أخذ القرى وهي ظالمة إن أخذه أليم شديد","ރަށްތައް (އެބަހީ: ރަށްތަކުގެ އަހުލުވެރިން) އަނިޔާވެރިވެގެންވާ ޙާލު، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެ ރަށްތައް ހިއްޕަވާހިނދު، އެކަލާނގެ ހިއްޕެވުންއޮތީ، އެފަދައިންނެވެ. ހަމަކަށަވަރުން، އެކަލާނގެ ހިއްޕެވުމަކީ، ވޭންދެނިވި، ގަދަފަދަ ކަމެކެވެ.","",""],["₁₁ سورة هود","103","إِنَّ فِي ذَٰلِكَ لَأٓيَةٗ لِّمَنۡ خَافَ عَذَابَ ٱلۡأٓخِرَةِۚ ذَٰلِكَ يَوۡمٞ مَّجۡمُوعٞ لَّهُ ٱلنَّاسُ وَذَٰلِكَ يَوۡمٞ مَّشۡهُودٞ ١٠٣","إن في ذلك لآية لمن خاف عذاب الآخرة ذلك يوم مجموع له الناس وذلك يوم مشهود","ހަމަކަށަވަރުން، އާޚިރަތްގެ އަޒާބަށް ބިރުވެތިވެއްޖެ މީހާއަށް އެކަމުގައި ހެތްކެއްވާކަން ކަށަވަރެވެ. އެއީ އެދުވަހަށްޓަކައި މީސްތަކުން އެއްކުރައްވާނޭ ދުވަހެކެވެ. އަދި އެއީ (އެންމެން) ދެކޭނޭ ދުވަހެކެވެ.","",""],["₁₁ سورة هود","104","وَمَا نُؤَخِّرُهُۥٓ إِلَّا لِأَجَلٖ مَّعۡدُودٖ ١٠٤","وما نؤخره إلا لأجل معدود","އަދި އަދަދުކުރައްވާފައިވާ މުއްދަތަކަށް މެނުވީ، ތިމަންރަސްކަލާނގެ އެދުވަސް ފަހެއް ނުކުރައްވަމެވެ.","",""],["₁₁ سورة هود","105","يَوۡمَ يَأۡتِ لَا تَكَلَّمُ نَفۡسٌ إِلَّا بِإِذۡنِهِۦۚ فَمِنۡهُمۡ شَقِيّٞ وَسَعِيدٞ ١٠٥","يوم يأت لا تكلم نفس إلا بإذنه فمنهم شقي وسعيد","އެދުވަސް އައުމުން، އެކަލާނގެ އިޒުނަ ފުޅާއެކުގައި މެނުވީ، އެއްވެސް ނަފްސަކަށް ބަހެއްވެސް ނުބުނެވޭނެތެވެ. ފަހެ، އަބާއްޖަވެރިންނާއި، ބާއްޖަވެރިން އެއުރެންގެ ތެރެއިންވެއެވެ.","",""],["₁₁ سورة هود","106","فَأَمَّا ٱلَّذِينَ شَقُواْ فَفِي ٱلنَّارِ لَهُمۡ فِيهَا زَفِيرٞ وَشَهِيقٌ ١٠٦","فأما الذين شقوا ففي النار لهم فيها زفير وشهيق","ފަހެ، އަބާއްޖަވެރިވި މީހުން ދަންނާށެވެ! ފަހެ، އެއުރެން ވާހުށީ، ނަރަކައިގައެވެ. އެއުރެން ބޭރަށްލާ ނޭވާގެ ގަދަ އަޑާއި، އެތެރެއަށްލާ ނޭވާގެ އަޑު އެތާނގައި ހުންނާނެތެވެ.","",""],["₁₁ سورة هود","107","خَٰلِدِينَ فِيهَا مَا دَامَتِ ٱلسَّمَٰوَٰتُ وَٱلۡأَرۡضُ إِلَّا مَا شَآءَ رَبُّكَۚ إِنَّ رَبَّكَ فَعَّالٞ لِّمَا يُرِيدُ ١٠٧","خالدين فيها ما دامت السماوات والأرض إلا ما شاء ربك إن ربك فعال لما يريد","އެއުރެން އެ ނަރަކައިގައި ދެމިތިބެނިވި ގޮތުގައެވެ. ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އިރާދަކުރެއްވި މުއްދަތެއް ފިޔަވައި، އުޑުތަކާއި، ބިން ދެމިހުރިހާ ހިނދެއްގައެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުންގެ ވެރިރަސްކަލާނގެއީ، އެކަލާނގެ އިރާދަކުރައްވާ ކަމެއް ކުރައްވާ ރަސްކަލާނގެއެވެ.","",""],["₁₁ سورة هود","108","۞وَأَمَّا ٱلَّذِينَ سُعِدُواْ فَفِي ٱلۡجَنَّةِ خَٰلِدِينَ فِيهَا مَا دَامَتِ ٱلسَّمَٰوَٰتُ وَٱلۡأَرۡضُ إِلَّا مَا شَآءَ رَبُّكَۖ عَطَآءً غَيۡرَ مَجۡذُوذٖ ١٠٨","وأما الذين سعدوا ففي الجنة خالدين فيها ما دامت السماوات والأرض إلا ما شاء ربك عطاء غير مجذوذ","އަދި ބާއްޖަވެރިވި މީހުން ދަންނާށެވެ! އެއުރެންވާހުށީ ސުވަރުގޭގައެވެ. އެތާނގައި، އެއުރެން ދެމިތިބެނިވި ގޮތުގައެވެ. ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އިރާދަކުރެއްވި މުއްދަތެއް ފިޔަވައި އުޑުތަކާއި ބިން ދެމިއޮތްހާ ހިނދެއްގައެވެ. ކެނޑިގެންނުދާ ދެއްވުމެއްގެ ގޮތުގައެވެ.","",""],["₁₁ سورة هود","109","فَلَا تَكُ فِي مِرۡيَةٖ مِّمَّا يَعۡبُدُ هَـٰٓؤُلَآءِۚ مَا يَعۡبُدُونَ إِلَّا كَمَا يَعۡبُدُ ءَابَآؤُهُم مِّن قَبۡلُۚ وَإِنَّا لَمُوَفُّوهُمۡ نَصِيبَهُمۡ غَيۡرَ مَنقُوصٖ ١٠٩","فلا تك في مرية مما يعبد هؤلاء ما يعبدون إلا كما يعبد آباؤهم من قبل وإنا لموفوهم نصيبهم غير منقوص","ފަހެ، މިބައިމީހުން އަޅުކަންކުރާ ފަރާތްތަކާ ބެހޭގޮތުން، ޝައްކުކަމެއްގައި ކަލޭގެފާނު ނުހުންނަވާށެވެ! ކުރިންވެސް އެއުރެންގެ ކާބަފައިން އަޅުކަންކުރާ ފަދައަކުން މެނުވީ، އެއުރެން އަޅުކަމެއް ނުކުރެތެވެ. އަދި ހަމަކަށަވަރުން، އުނިވުމެއްނެތި އެއުރެންގެ (އަޒާބުގެ) ބައި، އެބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ ހަމަޔަށް ދެއްވާހުށީމެވެ.","",""],["₁₁ سورة هود","110","وَلَقَدۡ ءَاتَيۡنَا مُوسَى ٱلۡكِتَٰبَ فَٱخۡتُلِفَ فِيهِۚ وَلَوۡلَا كَلِمَةٞ سَبَقَتۡ مِن رَّبِّكَ لَقُضِيَ بَيۡنَهُمۡۚ وَإِنَّهُمۡ لَفِي شَكّٖ مِّنۡهُ مُرِيبٖ ١١٠","ولقد آتينا موسى الكتاب فاختلف فيه ولولا كلمة سبقت من ربك لقضي بينهم وإنهم لفي شك منه مريب","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް ފޮތް ދެއްވީމެވެ. ފަހެ، އެ ފޮތާމެދު ޚިލާފު ވޫއެވެ. ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އިސްވެދިޔަ ބަސްފުޅެއް ނުވާނަމަ، އެއުރެންގެ މެދުގައި ނިޔާކުރެއްވީސްކަން ކަށަވަރެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެންވަނީ އެކަމާމެދު ވަސްވާސްތެރިކަމުން ފުރިގެންވާ ޝައްކެއްގައިކަން ކަށަވަރެވެ.","",""],["₁₁ سورة هود","111","وَإِنَّ كُلّٗا لَّمَّا لَيُوَفِّيَنَّهُمۡ رَبُّكَ أَعۡمَٰلَهُمۡۚ إِنَّهُۥ بِمَا يَعۡمَلُونَ خَبِيرٞ ١١١","وإن كلا لما ليوفينهم ربك أعمالهم إنه بما يعملون خبير","ހަމަކަށަވަރުން، ކޮންމެ ބަޔަކަށްވެސް އެބަޔެއްގެ ޢަމަލުތަކަށް ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަމަޔަށް ޖަޒާދެއްވާނެއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، އެއުރެންކުރާ ޢަމަލުތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₁₁ سورة هود","112","فَٱسۡتَقِمۡ كَمَآ أُمِرۡتَ وَمَن تَابَ مَعَكَ وَلَا تَطۡغَوۡاْۚ إِنَّهُۥ بِمَا تَعۡمَلُونَ بَصِيرٞ ١١٢","فاستقم كما أمرت ومن تاب معك ولا تطغوا إنه بما تعملون بصير","ފަހެ، ކަލޭގެފާނަށް އަމުރުކުރައްވާފައިވާ ފަދައިން، ކަލޭގެފާނުންގެ އަރިހުގައި އީމާންވެ، ތައުބާ ވެގެން ތިބިމީހުންނާއެކު، ކަލޭގެފާނު ސީދާވެވަޑައިގަންނަވާށެވެ! އަދި ތިޔަބައިމީހުން ހައްދުފަހަނަޅައި ނުދާށެވެ! ހަމަކަށަވަރުން، އެކަލާނގެއީ، ތިޔަބައިމީހުންކުރާ ކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["₁₁ سورة هود","113","وَلَا تَرۡكَنُوٓاْ إِلَى ٱلَّذِينَ ظَلَمُواْ فَتَمَسَّكُمُ ٱلنَّارُ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِنۡ أَوۡلِيَآءَ ثُمَّ لَا تُنصَرُونَ ١١٣","ولا تركنوا إلى الذين ظلموا فتمسكم النار وما لكم من دون الله من أولياء ثم لا تنصرون","އަދި އަނިޔާވެރިވި މީހުންގެ ފަރާތަށް ތިޔަބައިމީހުން ކުޑަކޮށްވެސް ނުލެނބޭށެވެ! ފަހެ، (އެ ހިނދުން) ނަރަކައިގެ އަލިފާން ތިޔަބައިމީހުންގައި ބީހިދާނެތެވެ. އަދި ﷲ ފިޔަވައި، ތިޔަބައިމީހުންނަށް އެހީތެރިވާނޭ އެއްވެސް ފަރާތެއް ނެތެވެ. ދެން ތިޔަބައިމީހުންނަކަށް ނަސްރެއްވެސް ނުލިބޭނެތެވެ.","",""],["₁₁ سورة هود","114","وَأَقِمِ ٱلصَّلَوٰةَ طَرَفَيِ ٱلنَّهَارِ وَزُلَفٗا مِّنَ ٱلَّيۡلِۚ إِنَّ ٱلۡحَسَنَٰتِ يُذۡهِبۡنَ ٱلسَّيِّـَٔاتِۚ ذَٰلِكَ ذِكۡرَىٰ لِلذَّـٰكِرِينَ ١١٤","وأقم الصلاة طرفي النهار وزلفا من الليل إن الحسنات يذهبن السيئات ذلك ذكرى للذاكرين","އަދި ދުވާލުގެ ދެކޮޅުގައްޔާއި، ރޭގަނޑުން ބައެއްގައި ކަލޭގެފާނު ނަމާދު ގާއިމުކުރައްވާށެވެ! ހަމަކަށަވަރުން، ހެޔޮކަންތައް، ނުބައިކަންތައް ނެތިކޮށްލަތެވެ. އެއީ ހަނދާންކުރާ ބަޔަކަށް ވައުޒާއި ނަސޭހަތެކެވެ.","",""],["₁₁ سورة هود","115","وَٱصۡبِرۡ فَإِنَّ ٱللَّهَ لَا يُضِيعُ أَجۡرَ ٱلۡمُحۡسِنِينَ ١١٥","واصبر فإن الله لا يضيع أجر المحسنين","އަދި ކަލޭގެފާނު ކެތްކުރައްވާށެވެ! ފަހެ، ހަމަކަށަވަރުން، އިހްސާން ތެރިންގެ ދަރުމަ، ﷲގެއްލެނި ނުކުރައްވާނެތެވެ.","",""],["₁₁ سورة هود","116","فَلَوۡلَا كَانَ مِنَ ٱلۡقُرُونِ مِن قَبۡلِكُمۡ أُوْلُواْ بَقِيَّةٖ يَنۡهَوۡنَ عَنِ ٱلۡفَسَادِ فِي ٱلۡأَرۡضِ إِلَّا قَلِيلٗا مِّمَّنۡ أَنجَيۡنَا مِنۡهُمۡۗ وَٱتَّبَعَ ٱلَّذِينَ ظَلَمُواْ مَآ أُتۡرِفُواْ فِيهِ وَكَانُواْ مُجۡرِمِينَ ١١٦","فلولا كان من القرون من قبلكم أولو بقية ينهون عن الفساد في الأرض إلا قليلا ممن أنجينا منهم واتبع الذين ظلموا ما أترفوا فيه وكانوا مجرمين","ފަހެ، އުއްމަތްތަކުގެ ތެރެއިން (ދީންވެރިކަމާއި ހެޔޮވިސްނުމުގެ ތެރެއިން) ބާކީއޮތް މިންވަރެއްގެ ވެރިބަޔަކު، ބިމުގައި ފަސާދަ ކޮށް އުޅުން ނަހީކޮށް ތިޔަބައިމީހުންގެ ކުރިން އުޅުނުނަމަ ކިހާ ރަނގަޅުހެއްޔެވެ! އެހެނެއްކަމަކު، ތިމަންރަސްކަލާނގެ ސަލާމަތްކުރެއްވި މީހުންގެ ތެރެއިން މަދުބަޔަކުވިއެވެ. އަދި އަނިޔާވެރިވި މީހުން، އެއުރެންނަށް ލިބުނު ތަނަވަސްކަމަށް ތަބާ ވޫއެވެ. (އެބަހީ: އެކަމުގެ ތެރެއަށް ގެނބި، އާޚިރަތް ހަނދާންނެތި ކޮށްލޫއެވެ.) އަދި ކުށްވެރިން ކަމުގައި އެއުރެން ވޫއެވެ.","",""],["₁₁ سورة هود","117","وَمَا كَانَ رَبُّكَ لِيُهۡلِكَ ٱلۡقُرَىٰ بِظُلۡمٖ وَأَهۡلُهَا مُصۡلِحُونَ ١١٧","وما كان ربك ليهلك القرى بظلم وأهلها مصلحون","ރަށްތަކުގެ އަހުލުވެރިން ރަނގަޅަށް ކަންތައްކުރާ ބަޔަކު ކަމުގައިވަނިކޮށް، އަނިޔާވެރިގޮތުގައި އެ ރަށްތައް ހަލާކު ކުރެއްވުމަކަށް، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އިރާދައެއް ނުކުރައްވަތެވެ.","",""],["₁₁ سورة هود","118","وَلَوۡ شَآءَ رَبُّكَ لَجَعَلَ ٱلنَّاسَ أُمَّةٗ وَٰحِدَةٗۖ وَلَا يَزَالُونَ مُخۡتَلِفِينَ ١١٨","ولو شاء ربك لجعل الناس أمة واحدة ولا يزالون مختلفين","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އިރާދަކުރެއްވިނަމަ، މީސްތަކުން އެއް އުއްމަތެއް ކަމުގައި ލައްވައިފީސްކަން ކަށަވަރެވެ. ނަމަވެސް ޚިލާފު ވުމުގައި އެއުރެން ފިލައިނުދެތެވެ.","",""],["₁₁ سورة هود","119","إِلَّا مَن رَّحِمَ رَبُّكَۚ وَلِذَٰلِكَ خَلَقَهُمۡۗ وَتَمَّتۡ كَلِمَةُ رَبِّكَ لَأَمۡلَأَنَّ جَهَنَّمَ مِنَ ٱلۡجِنَّةِ وَٱلنَّاسِ أَجۡمَعِينَ ١١٩","إلا من رحم ربك ولذلك خلقهم وتمت كلمة ربك لأملأن جهنم من الجنة والناس أجمعين","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ރަހުމަތް ލެއްވި ބަޔަކު މެނުވީއެވެ. އެކަލާނގެ އެއުރެން ހެއްދެވީ އެކަމަށްޓަކައެވެ. އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ބަސްފުޅު ފުރިހަމަވެފައިވެއެވެ. (އެ ބަސްފުޅަކީ) ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، މީސްތަކުންނާއި، ޖިންނީންނާއި، ދެ ބާވަތުން ނަރަކަ ފުރުއްވާހުށީމެވެ.","",""],["₁₁ سورة هود","120","وَكُلّٗا نَّقُصُّ عَلَيۡكَ مِنۡ أَنۢبَآءِ ٱلرُّسُلِ مَا نُثَبِّتُ بِهِۦ فُؤَادَكَۚ وَجَآءَكَ فِي هَٰذِهِ ٱلۡحَقُّ وَمَوۡعِظَةٞ وَذِكۡرَىٰ لِلۡمُؤۡمِنِينَ ١٢٠","وكلا نقص عليك من أنباء الرسل ما نثبت به فؤادك وجاءك في هذه الحق وموعظة وذكرى للمؤمنين","އަދި ރަސޫލުންގެ ޚަބަރުތަކުގެ ތެރެއިން މިއެންމެހާ ޚަބަރުތައް، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ކިޔައިދެއްވަނީ، އެއިން ތިމަންރަސްކަލާނގެ ކަލޭގެފާނުގެ ހިތްޕުޅު ސާބިތުކޮށްދެއްވުމަށެވެ. އަދި މި ޚަބަރު ތަކުގައި ކަލޭގެފާނާ ހަމަޔަށް އައިސްފައިވަނީ، ހައްގު ތެދުބަސްފުޅެވެ. އަދި މުއުމިނު ތަކުންނަށް ވައުޒަކާއި، ހަނދާންކޮށްދިނުމެކެވެ.","",""],["₁₁ سورة هود","121","وَقُل لِّلَّذِينَ لَا يُؤۡمِنُونَ ٱعۡمَلُواْ عَلَىٰ مَكَانَتِكُمۡ إِنَّا عَٰمِلُونَ ١٢١","وقل للذين لا يؤمنون اعملوا على مكانتكم إنا عاملون","އީމާން ނުވާ މީހުންނަށް ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންގެ ގޮތުގައި ތިބެގެން ތިޔަބައިމީހުން ޢަމަލު ކޮށްބަލާށެވެ! ހަމަކަށަވަރުން، ތިމަންމެންވެސް (ތިމަންމެންގެ ގޮތުގައި) ޢަމަލުކުރާނޫއެވެ.","",""],["₁₁ سورة هود","122","وَٱنتَظِرُوٓاْ إِنَّا مُنتَظِرُونَ ١٢٢","وانتظروا إنا منتظرون","އަދި ތިޔަބައިމީހުން އިންތިޒާރުކުރާށެވެ! ހަމަކަށަވަރުން، ތިމަންމެންވެސް، އިންތިޒާރުކުރާނޫއެވެ.","",""],["₁₁ سورة هود","123","وَلِلَّهِ غَيۡبُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ وَإِلَيۡهِ يُرۡجَعُ ٱلۡأَمۡرُ كُلُّهُۥ فَٱعۡبُدۡهُ وَتَوَكَّلۡ عَلَيۡهِۚ وَمَا رَبُّكَ بِغَٰفِلٍ عَمَّا تَعۡمَلُونَ ١٢٣","ولله غيب السماوات والأرض وإليه يرجع الأمر كله فاعبده وتوكل عليه وما ربك بغافل عما تعملون","އަދި އުޑުތަކާއި، ބިމުގެ ޣައިބު މިލްކު ވެގެންވަނީ، ﷲއަށެވެ. އަދި އެންމެހާ ކަންތައް ރުޖޫއަކުރައްވާހުށީ، އެކަލާނގެ ހަޒުރަތަށެވެ. ފަހެ، ކަލޭގެފާނު އެކަލާނގެއަށް އަޅުކަން ކުރައްވާށެވެ! އަދި އެކަލާނގެއަށް ވަކީލުކުރައްވާށެވެ! ތިޔަބައިމީހުންކުރާ ޢަމަލު ތަކާމެދު، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ޣާފިލުވެ ވޮޑިގެނެއް ނުވެތެވެ.","",""],["","","","بسم الله الرحمن الرحيم الر تلك آيات الكتاب المبين","ا ل ر (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.) މިއީ ފާޅުވެ ބަޔާންވެގެންވާ، ފޮތުގެ އާޔަތް ތަކެވެ.","",""],["","","","إنا أنزلناه قرآنا عربيا لعلكم تعقلون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެ ފޮތް ބާވައިލެއްވީ، އަރަބި ބަހުންއޮތް ގުރްއާނެއް ކަމުގައެވެ. އެއީ ތިޔަބައިމީހުން ވިސްނައި ފިކުރުކުރުމަށްޓަކައެވެ.","",""],["","","","نحن نقص عليك أحسن القصص بما أوحينا إليك هذا القرآن وإن كنت من قبله لمن الغافلين","އެންމެ ރިވެތި ވާހަކަތައް، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ކިޔައިދެއްވަމެވެ. (އެއީ) ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނަށް މި ގުރުއާން ވަހީކުރެއްވި ކުރެއްވުމުންނެވެ. އޭގެކުރިން، ކަލޭގެފާނު އެ ވާހަކަތައް ނުދަންނަ މީހުންގެ ތެރެއިން ވީނަމަވެހެވެ.","",""],["","","","إذ قال يوسف لأبيه يا أبت إني رأيت أحد عشر كوكبا والشمس والقمر رأيتهم لي ساجدين","ޔޫސުފުގެފާނު، އެކަލޭގެފާނުގެ ބައްޕާއަށް ވިދާޅުވިހިނދު، ހަނދުމަކުރާށެވެ! އޭ ބައްޕާއެވެ! ހަމަކަށަވަރުން، އެގާރަ ތަރިޔާއި، އިރާއި، ހަނދު، ތިމަންކަލޭގެފާނަށް ހުވަފެނުން ފެނިއްޖެއެވެ. ފެނުނީ، އެތަކެތި ތިމަންކަލޭގެފާނަށް ސަޖިދަކުރާތީއެވެ.","",""],["","","","قال يا بني لا تقصص رؤياك على إخوتك فيكيدوا لك كيدا إن الشيطان للإنسان عدو مبين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ ދަރިފުޅާއެވެ! ތިބާޔަށް ފެނުނު ހުވަފެން ތިބާގެ ބޭބޭމެންނަށް ކިޔައިނުދޭށެވެ! ފަހެ، އެއުރެން ތިބާޔަށް ނުބައި ރޭވުމެއް ރާވައިފާނެތެވެ. ހަމަކަށަވަރުން، ޝައިތާނާއަކީ، އިންސާނާއަށްހުރި، ފާޅުވެގެންވާ އަދާވަތް ތެރިއެކެވެ.","",""],["","","","وكذلك يجتبيك ربك ويعلمك من تأويل الأحاديث ويتم نعمته عليك وعلى آل يعقوب كما أتمها على أبويك من قبل إبراهيم وإسحاق إن ربك عليم حكيم","އަދި ހަމައެފަދައިން، ތިބާގެ ވެރިރަސްކަލާނގެ، ތިބާ ޚިޔާރުކުރައްވައި، ހުވަފެނުގެ ވާހަކަތައް، މާނަކުރުން ތިބާޔަށް ދަސްކޮށްދެއްވައި، އަދި ތިބާޔަށާއި، ޔައުގޫބުގެ ދަރިކޮޅަށް، އެކަލާނގެ ނިއުމަތްތައް ފުރިހަމަކޮށްދެއްވާނެތެވެ. (އެއީ) މީގެކުރިން، ތިބާގެ ދެކާފައިން ކަމަށްވާ، އިބްރާހީމްގެފާނާއި، އިސްޙާގުގެފާނަށް އެ ނިއުމަތްތައް ފުރިހަމަކޮށްދެއްވި ފަދައިންނެވެ. ހަމަކަށަވަރުން، ތިބާގެ ވެރިރަސްކަލާނގެއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","لقد كان في يوسف وإخوته آيات للسائلين","ޔޫސުފުގެފާނާއި، އެކަލޭގެފާނުގެ އަޚުންގެ ވާހަކައިގައި، ސުވާލުކުރާ މީހުންނަށް، ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","إذ قالوا ليوسف وأخوه أحب إلى أبينا منا ونحن عصبة إن أبانا لفي ضلال مبين","އެ އަޚު ންތައް، ބުނިހިނދު، ހަނދުމަކުރާށެވެ! ތިމަންމެންނީ، ގަދަފަދަ ޖަމާއަތެއްކަމުގައި ވާހިނދުވެސް، ޔޫސުފުގެފާނާއި، އޭނާގެ އަޚު (ބުންޔާމީން) ތިމަންމެންގެ ބައްޕާގެ އަރިހުގައި ލޮބުވެތިކަން މާބޮޑެވެ. ހަމަކަށަވަރުން، ތިމަންމެންގެ ބައްޕާވަނީ، ފާޅުވެގެންވާ މަގުއޮޅުމެއްގައެވެ.","",""],["","","","اقتلوا يوسف أو اطرحوه أرضا يخل لكم وجه أبيكم وتكونوا من بعده قوما صالحين","ތިޔަބައިމީހުން ޔޫސުފުގެފާނު ގަތުލު ކޮށްލާށެވެ! ނުވަތަ، ދުރު ބިމަކަށް އެކަލޭގެފާނު އެއްލައިލާށެވެ! އޭރުން ތިޔަބައިމީހުންގެ ބައްޕާގެ ހެޔޮކަން ތިޔަބައިމީހުންނަށް އެކަނި ލިބޭނެތެވެ. އަދި އެއަށްފަހު ތިޔަބައިމީހުން (ތައުބާވެ) ސާލިހު ރަނގަޅު ބައެއްކަމުގައި ވާނީއެވެ.","",""],["","","","قال قائل منهم لا تقتلوا يوسف وألقوه في غيابت الجب يلتقطه بعض السيارة إن كنتم فاعلين","އެއުރެންގެ ތެރެއިން ބުނާ މީހަކު ބުންޏެވެ. ތިޔަބައިމީހުން ޔޫސުފުގެފާނު ގަތުލު ނުކުރާށެވެ! ތިޔަބައިމީހުން ކަމެއްކުރަންޏާ (އަނދިރި) ވަޅެއްގެ އަޑިޔަށް އެކަލޭގެފާނު އެއްލައިލާށެވެ! އޭރުން، ދަތުރުކުރަމުންދާ ބަޔަކު، އެކަލޭގެފާނު ހޮވައިގެން ގެންގޮސްފާނެތެވެ.","",""],["","","","قالوا يا أبانا ما لك لا تأمنا على يوسف وإنا له لناصحون","އެއުރެން ދެންނެވޫއެވެ. އޭ އަހުރެމެންގެ ބައްޕާއެވެ! ޔޫސުފުގެފާނާމެދު، ކަލޭގެފާނު ތިމަންމެންނަށް އިތުބާރު ނުކުރައްވަނީ ކީއްވެތޯއެވެ. ހަމަކަށަވަރުން، ތިމަންމެންނީ، އެކަލޭގެފާނަށް ހެޔޮއެދޭ ބަޔަކީމުއެވެ.","",""],["","","","أرسله معنا غدا يرتع ويلعب وإنا له لحافظون","ކައިބޮއި އުފާކޮށް، ކުޅެހެދުމަށްޓަކައި، ތިމަންމެންނާއެކުގައި، މާދަމާ އެކަލޭގެފާނު ފޮނުއްވާށެވެ! ހަމަކަށަވަރުން، ތިމަންމެން އެކަލޭގެފާނު ބަލަހައްޓައި ރައްކާތެރިކުރާހުށީމުއެވެ.","",""],["","","","قال إني ليحزنني أن تذهبوا به وأخاف أن يأكله الذئب وأنتم عنه غافلون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭނާ ގޮވައިގެން ތިޔަބައިމީހުން ދިއުމަކީ، ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނަށް ހިތާމަ ލިބޭކަމެކެވެ. އަދި ތިޔަބައިމީހުން އޭނާގެ މަތިން ޣާފިލު ވެގެންތިއްބައި، މިނިކާވަގު (އައިސް) އޭނާ ކައިފާނެތީ ތިމަންކަލޭގެފާނު ބިރުފުޅު ގަނެތެވެ.","",""],["","","","قالوا لئن أكله الذئب ونحن عصبة إنا إذا لخاسرون","އެއުރެން ދެންނެވޫއެވެ. ތިމަންމެންނީ ބާރުހުރި ބަޔެއްކަމަށްވާހިނދު، މިނިކާވަގު (އައިސް) އޭނާ ކައިފިނަމަ، ހަމަކަށަވަރުން، ތިމަންމެންވާހުށީ (ކަމެއްނުކުރެވޭ) ގެއްލެނިވިގެންވާ ބަޔަކު ކަމުގައެވެ.","",""],["","","","فلما ذهبوا به وأجمعوا أن يجعلوه في غيابت الجب وأوحينا إليه لتنبئنهم بأمرهم هذا وهم لا يشعرون","ފަހެ، އެއުރެން އެކަލޭގެފާނު ގޮވައިގެން ދިޔަހިނދު، އަނދިރި ވަޅަކަށް އެކަލޭގެފާނު ލުމަށް އެންމެން އެއްބަސްވޫއެވެ. ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ވަހީކުރެއްވީމެވެ. އެއުރެންގެ މިކަންތަކުގެ ވާހަކަ، އެއުރެންނަށް ނޭނގިތިއްބައި، ހަމަކަށަވަރުން، ކަލޭގެފާނު އެއުރެންނަށް (ފަހުން) ކިޔައިދެއްވާނެތެވެ.","",""],["","","","وجاءوا أباهم عشاء يبكون","އަދި ޢިޝާ ވަގުތުގައި، އެއުރެންގެ ބައްޕާގެ އަރިހަށް ރޮމުން އެއުރެން އައޫއެވެ.","",""],["","","","قالوا يا أبانا إنا ذهبنا نستبق وتركنا يوسف عند متاعنا فأكله الذئب وما أنت بمؤمن لنا ولو كنا صادقين","އެއުރެން ދެންނެވޫއެވެ. އޭ އަހުރެމެންގެ ބައްޕާއެވެ! ތިމަންމެންގެ ސާމާނުތަކުގެ ކައިރީގައި ޔޫސުފުގެފާނު ބަހައްޓާފައި، ތިމަންމެން ވާދަކުރުމަށް ދިޔައީމުއެވެ. ދެން މިނިކާވަގެއްއައިސް، އެކަލޭގެފާނު ކައިފިއެވެ. ތިމަންމެން ތެދުވެރިންކަމުގައިވިޔަސް، ކަލޭގެފާނު ތިމަންމެންގެ ބަސް ތެދެއް ނުކުރައްވާނެތެވެ.","",""],["","","","وجاءوا على قميصه بدم كذب قال بل سولت لكم أنفسكم أمرا فصبر جميل والله المستعان على ما تصفون","އަދި އެއުރެން އެކަލޭގެފާނުގެ ގަމީސްކޮޅުގައި ދޮގު ލެޔެއް އުނގުޅައިގެން ގެނައޫއެވެ. (ޔައުގޫބުގެފާނު) ވިދާޅުވިއެވެ. އެހެންނަކުންނޫނެވެ. ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތައް (ނުބައި) ކަމެއްކުރުމަށް، ތިޔަބައިމީހުންނަށް ތަންދިނީއެވެ. ފަހެ، (ތިމަންކަލޭގެފާނަށް އޮތީ) ރިވެތިވެގެންވާ ކެތްކުރުމެކެވެ. އަދި ތިޔަބައިމީހުން، ސިފަކޮށް ބުނާ އެއްޗެއްގެ މައްޗަށް (ކެތްކުރުމުގައި) އެހީދެއްވާ ފަރާތަކީ ﷲއެވެ.","",""],["","","","وجاءت سيارة فأرسلوا واردهم فأدلى دلوه قال يا بشرى هذا غلام وأسروه بضاعة والله عليم بما يعملون","އެތަނަށް ދަތުރުކުރާ ބަޔަކު އައޫއެވެ. އަދި އެއުރެންނަށް ފެން ގެނެސްދޭމީހާ (ވަޅުކައިރިއަށް) ފޮނުވޫއެވެ. އަދި އޭނާ ބާލިދީ ވަޅަށް ތިރިކޮށްފައި (ޔޫސުފުގެފާނު ވަޅުން ނަގާފައި) ބުންޏެވެ. އޭ ހުރި އުފަލެއްގެ ބޮޑުކަމާއެވެ! މިހުރީ ކުޑަ ފިރިހެން ކުއްޖެކެވެ. ދެން ވިޔަފާރި މުދަލެއްގެ ގޮތުގައި، އެކަލޭގެފާނު ފޮރުވައި، ރައްކާކޮށްފޫއެވެ. ﷲއީ، އެމީހުން ކުރާ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وشروه بثمن بخس دراهم معدودة وكانوا فيه من الزاهدين","އަދި ވަރަށް ކުޑަ އަގަކަށް، ގުނައިލެވޭ މަދު ދިރުހަމް ކޮޅަކަށް، އެއުރެން އެކަލޭގެފާނު ވިއްކާލައިފޫއެވެ. އަދި އެކަލޭގެފާނާމެދު، އެއުރެންވީ (މަދު އެތިކޮޅަކަށް ރުހޭ) ޒާހިދުންގެ ތެރެއިންނެވެ.","",""],["","","","وقال الذي اشتراه من مصر لامرأته أكرمي مثواه عسى أن ينفعنا أو نتخذه ولدا وكذلك مكنا ليوسف في الأرض ولنعلمه من تأويل الأحاديث والله غالب على أمره ولكن أكثر الناس لا يعلمون","މިސްރުން އެކަލޭގެފާނު ގަތް މީހާ، އޭނާގެ އަންހެނުންނަށް ބުންޏެވެ. ކަނބުލޭގެ، އެކަލޭގެފާނުގެ ހުންނެވުން ރަނގަޅުގޮތަކަށް ހަމަޖައްސާށެވެ! އެއީ އެކަލޭގެފާނު، ތިމަންމެންނަށް މަންފާއެއް ކުރޭތޯއެވެ. ނުވަތަ ތިމަންމެން އެކަލޭގެފާނު ދަރިއެއްކަމުގައި ހަދާނީއެވެ. އެފަދައިން، ތިމަންރަސްކަލާނގެ ޔޫސުފުގެފާނު (މިސްރުގެ) ބިމުގައި ބާރުވެރި ކުރެއްވީމެވެ. އަދި ހުވަފެނުގެ ވާހަކަތައް މާނަކުރެއްވުން އެކަލޭގެފާނަށް ދަސްކޮށްދެއްވުމަށްޓަކައެވެ. ﷲއީ، އެކަލާނގެ ކަންތައްތައް ހިންގެވުމުގައި، ބާރުވެރިވަންތަ ރަސްކަލާނގެއެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުން (އެކަމެއް) ނުދަނެތެވެ.","",""],["","","","ولما بلغ أشده آتيناه حكما وعلما وكذلك نجزي المحسنين","އެކަލޭގެފާނު ފުރާ ފުރިހަމަވީހިނދު، ތިމަންރަސްކަލާނގެ، އެކަލޭގެފާނަށް ހިކުމަތާއި، އިލްމު ދެއްވީމެވެ. އިހްސާން ތެރިންނަށް ތިމަންރަސްކަލާނގެ ޖަޒާދެއްވަނީ، އެފަދައިންނެވެ.","",""],["","","","وراودته التي هو في بيتها عن نفسه وغلقت الأبواب وقالت هيت لك قال معاذ الله إنه ربي أحسن مثواي إنه لا يفلح الظالمون","އަދި އެކަލޭގެފާނު އެކަނބުލޭގެ ގޭގައި ހުންނެވި ކަނބުލޭގެ، އެކަލޭގެފާނުގެ އަރިހުން ނުބައި ކަމަކަށް އެދުނެވެ. އަދި ދޮރުލައްޕައި، އެކަނބުލޭގެ ދެންނެވިއެވެ. ކަލޭގެފާނު (ތިމަންނާގެ ގާތަށް) ވަޑައިގަންނަވާށެވެ! އެކަލޭގެފާނު ވިދާޅުވިއެވެ. [معاذ ﷲ] އެވެ. (އެބަހީ: ﷲގެ ރައްކާތެރިކަމަށް އެދެމެވެ. ޚިޔާނަތް ތެރިވުމަށް ކަނބުލޭގެ ތިޔަ އެދޭ މީހާ) އެއީ ހަމަކަށަވަރުން، ތިމަންގެ ސާހިބު މީހާއެވެ. އޭނާ ތިމަންކަލޭގެފާނު ބަހައްޓާފައިވަނީ، މާތް ރަނގަޅުގޮތަށެވެ. ހަމަކަށަވަރުން، އަނިޔާވެރިން ނުދިނޭނެތެވެ.","",""],["","","","ولقد همت به وهم بها لولا أن رأى برهان ربه كذلك لنصرف عنه السوء والفحشاء إنه من عبادنا المخلصين","އަދި ހަމަކަށަވަރުން (އެދުމާއެކު) އެކަނބުލޭގެ އެކަލޭގެފާނާ ކުރިމަތިލިއެވެ. އަދި އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ދަލީލު ފެނިވަޑައިނުގެންނެވިނަމަ، އެކަލޭގެފާނުގެ ހިތްޕުޅުވެސް އެކަނބުލޭގެ ފަރާތަށް ލެނބުނީހެވެ. އެފަދައިން (އެ ދަލީލު ދެއްކެވީ) ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނުގެ ކިބައިން ނުބައި ޢަމަލާއި، ހުތުރުކަންބޮޑު ފާފަ ދުރުކުރެއްވުމަށްޓަކައެވެ. ހަމަކަށަވަރުން، އެކަލޭގެފާނު ވަނީ، ތިމަންރަސްކަލާނގެ ޚިޔާރުކުރެއްވި އަޅުންގެ ތެރެއިންނެވެ.","",""],["","","","واستبقا الباب وقدت قميصه من دبر وألفيا سيدها لدى الباب قالت ما جزاء من أراد بأهلك سوءا إلا أن يسجن أو عذاب أليم","އަދި އެ ދެމީހުންމެ ދޮރާ ދިމާއަށް އަވަސްވެގެންފޫއެވެ. އަދި އެކަނބުލޭގެ އެކަލޭގެފާނުގެ ގަމީސްކޮޅު ފުރަގަހުން (ހިފައި) ވީދައިލިއެވެ. އަދި ދޮރުކައިރިން އެކަނބުލޭގެ ފިރިމީހާ އެ ދެމީހުންނަށް ފެނުނެވެ. އެކަނބުލޭގެ ބުންޏެވެ. ތިބާގެ އަނބިމީހާއަށް ނުބައިކަމެއްކުރަން އުޅުނުމީހަކަށް، އެމީހާ ޖަލުގައި ހައްޔަރުކުރުން، ނުވަތަ ވޭންދެނިވި އުގޫބާތް ދިނުން ފިޔަވައި އޮތީ ކޮން ޖަޒާއެއް ހެއްޔެވެ؟","",""],["","","","قال هي راودتني عن نفسي وشهد شاهد من أهلها إن كان قميصه قد من قبل فصدقت وهو من الكاذبين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ނުބައިކަންތަކަށް ތިމަންކަލޭގެފާނުގެ ކިބައިން އެދުނީ، އެކަނބުލޭގެއެވެ. އަދި (އެކަމާމެދު) އެކަނބުލޭގެ ތިމާގެ މީހުންކުރެ ހެކިވެރިޔަކު ހެކިދީ ބުންޏެވެ. އެކަލޭގެފާނުގެ ގަމީސްކޮޅު ވީދިފައިވަނީ، ކުރިމަތިންނަމަ، އެކަނބުލޭގެ އެބުނީ ތެދެވެ. އަދި އެކަލޭގެފާނު ވަނީ ދޮގުވެރިންގެ ތެރެއިންނެވެ.","",""],["","","","وإن كان قميصه قد من دبر فكذبت وهو من الصادقين","އަދި އެކަލޭގެފާނުގެ ގަމީސްކޮޅު ވީދިފައިވަނީ، ފުރަގަހުންނަމަ، އެކަނބުލޭގެ އެހެދީ ދޮގެވެ. އަދި އެކަލޭގެފާނު އެވަނީ ތެދުވެރިންގެ ތެރެއިންނެވެ.","",""],["","","","فلما رأى قميصه قد من دبر قال إنه من كيدكن إن كيدكن عظيم","ފަހެ، އެކަލޭގެފާނުގެ ގަމީސްކޮޅު ފުރަގަހުން ވީދިފައިވާތަން ފެނުމުން، އޭނާ (އެބަހީ: އެކަނބުލޭގެ ފިރިމީހާ) ބުންޏެވެ. ހަމަކަށަވަރުން، އެއީ ތިޔަކަނބަލުންގެ މަކަރުވެރިކަމުގެ ތެރެއިން ކަމެކެވެ. ހަމަކަށަވަރުން، ތިޔަކަނބަލުންގެ މަކަރުވެރިކަމަކީ، ބޮޑުވެގެންވާ ކަމެކެވެ.","",""],["","","","يوسف أعرض عن هذا واستغفري لذنبك إنك كنت من الخاطئين","ޔޫސުފުގެފާނެވެ! މިކަންތަކުން ދުރުހެލިވެވަޑައިގަންނަވާށެވެ! އަދި ކަނބުލޭގެ ކުރި ކުށަށް މާފު އެދޭށެވެ! ހަމަކަށަވަރުން، ކަނބުލޭގެވަނީ، ކުށްވެރިންގެ ތެރެއިންނެވެ.","",""],["","","","وقال نسوة في المدينة امرأت العزيز تراود فتاها عن نفسه قد شغفها حبا إنا لنراها في ضلال مبين","(މިކަންތަކުގެ ޚަބަރު ފެތުރިގެންދިޔުމުން) ރަށުތެރޭގެ އަންހެނުންގެ ބަޔަކު ބުނެފޫއެވެ. އަލްޢަޒީޒުގެ އަންހެނުން، އެކަނބުލޭގެ އަޅުކުއްޖާގެ ކިބައިން ނުބައިކަންތަކަށް އެދެނީއެވެ. ހަމަކަށަވަރުން، އެކަނބުލޭގެ ހިތްވަނީ، އެކުއްޖާގެ ލޯބިން ފުރިފައެވެ. ހަމަކަށަވަރުން، އެކަނބުލޭގެ ވާކަމަށް ތިމަންމެންދެކެނީ ބަޔާންވެގެންވާ ފުރެދުމެއްގައެވެ.","",""],["","","","فلما سمعت بمكرهن أرسلت إليهن وأعتدت لهن متكأ وآتت كل واحدة منهن سكينا وقالت اخرج عليهن فلما رأينه أكبرنه وقطعن أيديهن وقلن حاش لله ما هذا بشرا إن هذا إلا ملك كريم","ފަހެ، އެ އަންހެނުން ދެއްކި (މަލާމާތުގެ) މަކަރުވެރި ވާހަކަ އެކަނބުލޭގެއަށް އިވުމުން، އެއުރެން ބަލައިފޮނުވިއެވެ. އަދި ލެނގިގެންތިބޭނެ ތަނެއް ތައްޔާރުކުރިއެވެ. އަދި އެއިންކޮންމެ މީހަކަށް ފިޔޮއްސެއް ދިނެވެ. އަދި ޔޫސުފުގެފާނަށް ދެންނެވިއެވެ. އެއުރެންގެ ތެރެޔަށް ނުކުމެވަޑައިގަންނަވާށެވެ! ދެން، އެ އަންހެނުން އެކަލޭގެފާނު ދުށްހިނދު، އެއުރެން އެކަލޭގެފާނުގެ ރީތިކަމާމެދު ހައިރާން ވޫއެވެ. އަދި އެއުރެން އަތްތައް ކޮށަމުން ދިޔައޫއެވެ. އަދި ބުނެފޫއެވެ. [حاش للَّه] އެވެ. (ﷲގެ ހުސްތާހިރުވަންތަ ކަމާއެވެ!) މިއީއަކީ އާދަމުގެދަރިއެއްވާ ނޫނެވެ. މިއީ ހަމަކަށަވަރުން، މާތްވެގެންވާ މަލާއިކަތަކު ކަމުގައި ނޫނީ ނުވެތެވެ.","",""],["","","","قالت فذلكن الذي لمتنني فيه ولقد راودته عن نفسه فاستعصم ولئن لم يفعل ما آمره ليسجنن وليكونا من الصاغرين","އެކަނބުލޭގެ ބުންޏެވެ. ތިޔަބައިމީހުން ތިމަންނާއަށް މަލާމާތްކޮށް ވާހަކަދެއްކީ، އޭނާއާ މެދުގައެވެ. ހަމަކަށަވަރުން، ތިމަން އޭނާގެ ކިބައިން ނުބައިކަންތަކަށް އެދުނީއެވެ. ފަހެ، އެހިނދު އޭނާ އެކަމުން ރައްކާތެރިވެގަތެވެ. އަދި ތިމަން އޭނާއަށް އަމުރުކުރާ ކަންތައް ނުކުޅަނަމަ، ޖަލުގައި އޭނާ ހައްޔަރު ކުރެވޭނެކަން ކަށަވަރެވެ. އަދި އޭނާ ވާހުށީ، ނިކަމެތިވެގެންވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["","","","قال رب السجن أحب إلي مما يدعونني إليه وإلا تصرف عني كيدهن أصب إليهن وأكن من الجاهلين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ތިމަންއަޅާ ކުރުމަށް އެއުރެން އެ އެދޭކަންތަކަށްވުރެ، ޖަލުގައި ހައްޔަރުވުންވެސް، ތިމަންއަޅާއަށް ލޮބުވެތިކަން މާބޮޑެވެ. އަދި އިބަރަސްކަލާނގެ އެއުރެންގެ މަކަރުވެރިކަން ތިމަން އަޅާގެ ކިބައިން ދުރުނުކުރެއްވިނަމަ، ތިމަންއަޅާ އެއުރެންނަށް ލެނބިގެން ހިނގައިދާނެތެވެ. އަދި ޖާހިލުންގެ ތެރެއިން ތިމަންއަޅާ ވެދާނެތެވެ.","",""],["","","","فاستجاب له ربه فصرف عنه كيدهن إنه هو السميع العليم","ފަހެ، އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެކަލޭގެފާނުގެ ދުއާ އިޖާބަކުރައްވައި، އެއުރެންގެ މަކަރުވެރިކަން އެކަލޭގެފާނުގެ ކިބައިން ދުރުކުރެއްވިއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ثم بدا لهم من بعد ما رأوا الآيات ليسجننه حتى حين","ދެން (އެކަލޭގެފާނު ބަރީއަވެގެންވާކަމުގެ) ދަލީލުތައް އެއުރެންނަށް ފެނިދިއުމަށްފަހުވެސް، ހަމަކަށަވަރުން، އެކަލޭގެފާނު ދުވަސްކޮޅަކަށް ޖަލުގައި ހައްޔަރުކުރުމަށް އެއުރެންނަށް ފެނުނެވެ.","",""],["","","","ودخل معه السجن فتيان قال أحدهما إني أراني أعصر خمرا وقال الآخر إني أراني أحمل فوق رأسي خبزا تأكل الطير منه نبئنا بتأويله إنا نراك من المحسنين","އަދި (ރަސްގެފާނުގެ ޚާދިމުންގެ ތެރެއިންވާ) ދެކުއްޖަކުވެސް އެކަލޭގެފާނުގެ އަރިހުގައި ޖަލަށްލެވުނެވެ. އޭގެތެރެއިން އެކަކު ދެންނެވިއެވެ. ހަމަކަށަވަރުން، ރާހެދުމަށް، ތިމަން މޭބިސްކަދުރުން ދިޔަފެލާތީ ތިމަންނާއަށް ހުވަފެނުން ފެނުނެވެ. އަދި އަނެކަކު ދެންނެވިއެވެ. ހަމަކަށަވަރުން، ތިމަންގެ ބޮލުގައި ރޮށިތަކެއް ބަހައްޓައިގެން ދަނިކޮށް، ދޫނި އެއިން ކާތީ ތިމަންނާއަށް ހުވަފެނުން ފެނުނެވެ. މިކަމުގެ މާނަ ތިމަންމެންނަށް ކަލޭގެފާނު ކިޔައިދެއްވާށެވެ! ހަމަކަށަވަރުން، ތިމަންމެން ކަލޭގެފާނު ދެކެނީ، އިހްސާން ތެރިންގެ ތެރެއިންވާ ބޭކަލަކު ކަމުގައެވެ.","",""],["","","","قال لا يأتيكما طعام ترزقانه إلا نبأتكما بتأويله قبل أن يأتيكما ذلكما مما علمني ربي إني تركت ملة قوم لا يؤمنون بالله وهم بالآخرة هم كافرون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަ ދެމީހުންނަށް ލިބޭ ކާނާއެއް ތިޔަ ދެމީހުންނަށް އައުމުގެ ކުރިން، ތިމަންކަލޭގެފާނު ތިޔަ ދެމީހުންނަށް އެއީ ކޮންއެއްޗެއްކަން އަންގައިދެއްވާހުށީމެވެ. އެއީ ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ތިމަންކަލޭގެފާނަށް އުނގަންނައިދެއްވި ކަންތަކުގެ ތެރެއިން ކަމެކެވެ. ﷲއަށް އީމާން ނުވާ ބަޔެއްގެ ދީން ހަމަކަށަވަރުން، ތިމަން ދޫކޮށްލައިފީމެވެ. އަދި އެއުރެންނީ، ހަމަ، އާޚިރަތަށް ކާފިރު ވެގެންވާ ބަޔެކެވެ.","",""],["","","","واتبعت ملة آبائي إبراهيم وإسحاق ويعقوب ما كان لنا أن نشرك بالله من شيء ذلك من فضل الله علينا وعلى الناس ولكن أكثر الناس لا يشكرون","އަދި ތިމަންކަލޭގެފާނުގެ ކާބަފައިކަލުނަވި އިބްރާހީމްގެފާނާއި، އިސްޙާގުގެފާނާއި، ޔައުގޫބުގެފާނުގެ ދީނަށް ތިމަންކަލޭގެފާނު ތަބާ ވެވަޑައިގަތީމެވެ. ﷲއަށް އެއްވެސް އެއްޗެއް ޝަރީކުކުރުމަކީ ތިމަންމެންނަށް އޮތްކަމެއްނޫނެވެ. އެއީ ތިމަންމެންނަށާއި، މީސްތަކުންނަށް ﷲ ދެއްވި ފަޟްލު ވަންތަކަމުގެ ތެރެއިންވާ ކަމެކެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުން (އެކަލާނގެއަށް) ޝުކުރެއް ނުކުރެތެވެ.","",""],["","","","يا صاحبي السجن أأرباب متفرقون خير أم الله الواحد القهار","އޭ ޖަލުގެ ދެ އެކުވެރިންނޭވެ! ވަކިވަކިވެގެންވާ ކަލާނގެ ތަކެއްހޭ ރަނގަޅީ، ނުވަތަ އެއްކައުވަންތަ، ބާރުވެރިވަންތަ ﷲ ހެއްޔެވެ؟","",""],["","","","ما تعبدون من دونه إلا أسماء سميتموها أنتم وآباؤكم ما أنزل الله بها من سلطان إن الحكم إلا لله أمر ألا تعبدوا إلا إياه ذلك الدين القيم ولكن أكثر الناس لا يعلمون","ތިޔަބައިމީހުންނާއި، ތިޔަބައިމީހުންގެ ކާބަފައިން އެ އެއްޗިއްސަށް ނަންދީފައިވާ އެއްޗެހިތަކަކަށްމެނުވީ، ﷲ ފިޔަވައި ތިޔަބައިމީހުން އަޅުކަމެއް ނުކުރަމުއެވެ. އެ އެއްޗަކަށް (އަޅުކަންކުރުމަށް) އެއްވެސް ހުއްޖަތެއް ﷲ ބާވައެއްނުލައްވަތެވެ. ﷲއަށް މެނުވީ ހުކުމްކުރެއްވުމެއްނެތެވެ. އެކަލާނގެއަށް ފިޔަވައި ތިޔަބައިމީހުން އަޅުކަން ނުކުރުމަށް އެކަލާނގެ ވަނީ އަމުރުކުރައްވާފައެވެ. އެއީ ހައްގު ތެދު ދީނެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުން (އެކަމެއް) ނުދަނެތެވެ.","",""],["","","","يا صاحبي السجن أما أحدكما فيسقي ربه خمرا وأما الآخر فيصلب فتأكل الطير من رأسه قضي الأمر الذي فيه تستفتيان","އޭ ޖަލުގެ ދެ އެކުވެރިންނޭވެ! ތިޔަ ދެމީހުންކުރެ އެކަކު ދަންނާށެވެ! ފަހެ، އޭނާގެ ސާހިބުމީހާއަށް އޭނާ ރާ ދޭނެތެވެ. އަދި އަނެކަކު ދަންނާށެވެ! ފަހެ، އޭނާ ޞަލީބަށް އެރުވޭނެތެވެ. ދެން އޭނާގެ ބޮލުން ދޫނި ކާނެތެވެ. ތިޔަ ދެމީހުން އޮޅުންފިލުވަން އުޅޭކަންތައްވަނީ (އެގޮތަށް) ނިޔާކުރައްވާފައެވެ.","",""],["","","","وقال للذي ظن أنه ناج منهما اذكرني عند ربك فأنساه الشيطان ذكر ربه فلبث في السجن بضع سنين","އެ ދެމީހުންކުރެ ނަޖާވާނެކަމަށް ހީކުރެއްވި މީހާއަށް އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިމަންކަލޭގެފާނުގެ ވާހަކަ، ތިބާގެ ސާހިބުމީހާގެ ގާތުގައި ކިޔައިދޭށެވެ! ފަހެ، އޭނާގެ ސާހިބުމީހާގެ ގާތުގައި އެވާހަކަދައްކަން ޝައިތާނާ އޭނާ ހަނދާން ނެއްތިއެވެ. ފަހެ (އެކަމުގެ ސަބަބުން) އެކަލޭގެފާނު ޖަލުގައި (އިތުރު) އެތައްއަހަރަކު ހުންނެވިއެވެ.","",""],["","","","وقال الملك إني أرى سبع بقرات سمان يأكلهن سبع عجاف وسبع سنبلات خضر وأخر يابسات يا أيها الملأ أفتوني في رؤياي إن كنتم للرؤيا تعبرون","ރަސްގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިމަންނާއަށް (ހުވަފެނުގައި) ފަލަ ހަތް ގެރި ފެނެއެވެ. (ފެންނަނީ) ހިކި ހަތް ގެރި، އެ ގެރިތައް ކަނިކޮންނެވެ. އަދި ރޯ ހަތް ކުރާއާއި، ހިކި ހަތް ކުރާ ފެނެއެވެ. އޭ ބޮޑުންނޭވެ! ތިޔަބައިމީހުން ހުވަފެނުގެ މާނަ ކިޔައިދޭ ބަޔަކު ކަމުގައިވާނަމަ، އަހުރެންގެ މި ހުވަފެނާ މެދުގައި، އަހުރެންނަށް އޮޅުންފިލުވައިދޭށެވެ!","",""],["","","","قالوا أضغاث أحلام وما نحن بتأويل الأحلام بعالمين","އެއުރެން ދެންނެވޫއެވެ. (ތިޔައީ) ހުވަފެނުގެ ހާސަރެކެވެ. އަދި (އެކަހަލަ) ހުވަފެން މާނަކުރަން ދަންނަ ބަޔަކު ކަމުގައި ތިމަންމެން ނުވަމުއެވެ.","",""],["","","","وقال الذي نجا منهما وادكر بعد أمة أنا أنبئكم بتأويله فأرسلون","އަދި އެ ދެމީހުންކުރެ (ޖަލުން) ސަލާމަތްވީމީހާ އެތައްދުވަހެއް ފަހުން (ޔޫސުފުގެފާނު މަތިން) ހަނދާންވެގެން ބުންޏެވެ. އެ ހުވަފެނުގެ މާނަ ތިޔަބައިމީހުންނަށް ތިމަން ކިޔައިދީފާހުށީމެވެ. ފަހެ، ތިޔަބައިމީހުން (ޔޫސުފުގެފާނުގެ އަރިހަށް) ތިމަން ފޮނުވާށެވެ!","",""],["","","","يوسف أيها الصديق أفتنا في سبع بقرات سمان يأكلهن سبع عجاف وسبع سنبلات خضر وأخر يابسات لعلي أرجع إلى الناس لعلهم يعلمون","(އޭނާ ދެންނެވިއެވެ.) އޭ ޔޫސުފުގެފާނެވެ! އޭ ތެދުވެރިޔާއެވެ! ހިކި ހަތް ގެރި (ވެގެން) ކާ، ފަލަ ހަތް ގެރިއާއި، ރޯ ހަތް ކުރާއާއި، ހިކި ހަތް ކުރާއާމެދު (އެބަހީ: އެ ހުވަފެނާމެދު) އަހުރެމެންނަށް އޮޅުންފިލުއްވައި ދެއްވާށެވެ! (އެއީ) ތިމަން އެއުރެން ގާތަށް އެނބުރިގޮސް ކިޔައިދިނުމަށްޓަކައެވެ. (އެއީ) އެއުރެންނަށް (އެކަން) އެނގުމަށްޓަކައެވެ.","",""],["","","","قال تزرعون سبع سنين دأبا فما حصدتم فذروه في سنبله إلا قليلا مما تأكلون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ވިދިވިދިގެން ހަތް އަހަރުވަންދެން ތިޔަބައިމީހުން ގޮވާންކުރާ ހުށިކަމެވެ! އަދި ތިޔަބައިމީހުން ކަނޑާ ގޮވާމެއް، ކުރާގަނޑުގައި ބަހައްޓާށެވެ! ކެއުމަށް ބޭނުންކުރާ މަދު އެތިކޮޅެއް މެނުވީއެވެ.","",""],["","","","ثم يأتي من بعد ذلك سبع شداد يأكلن ما قدمتم لهن إلا قليلا مما تحصنون","ދެން އެއަށްފަހު، ތަދުމަޑު ހަތް އަހަރު އަންނާނެތެވެ. ތިޔަބައިމީހުން ރައްކާކުރި ތަކެތިން މަދުއެތިކޮޅެއް މެނުވީ، އެ އަހަރުތަކަށް ބަހައްޓާފައިހުރި ތަކެތި ތިޔަބައިމީހުން ކައިހުސްކުރާނޫއެވެ.","",""],["","","","ثم يأتي من بعد ذلك عام فيه يغاث الناس وفيه يعصرون","ދެން އެއަށްފަހު، މީސްތަކުންނަށް ވާރޭފެން ގިނައިން ލިބޭނޭ އަހަރެއް އަންނާނެތެވެ. އަދި އެ އަހަރުގައި އެއުރެން (ދިޔަފެލާ ތަކެތިން) ދިޔަފެލާނެތެވެ.","",""],["","","","وقال الملك ائتوني به فلما جاءه الرسول قال ارجع إلى ربك فاسأله ما بال النسوة اللاتي قطعن أيديهن إن ربي بكيدهن عليم","ރަސްގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން ތިމަންގެ ގާތަށް އޭނާ ގެންނާށެވެ! ފަހެ، ރަސްގެފާނު ފޮނުއްވި މީހާ އެކަލޭގެފާނުގެ އަރިހަށް އައުމުން، ވިދާޅުވިއެވެ. ތިބާގެ ސާހިބުމީހާގެ ގާތަށް ތިބާ އެނބުރި ހިނގައިދާށެވެ! ފަހެ، އެއުރެންގެ އަތްތައް ކޮށައިލި އަންހެނުންތަކަށް ވީގޮތަކާމެދު، އޭނާއާ ސުވާލުކޮށްބަލާށެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެއުރެންގެ މަކަރުވެރިކަން މޮޅަށް ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","قال ما خطبكن إذ راودتن يوسف عن نفسه قلن حاش لله ما علمنا عليه من سوء قالت امرأت العزيز الآن حصحص الحق أنا راودته عن نفسه وإنه لمن الصادقين","އޭނާ (އެބަހީ: ރަސްގެފާނު) ވިދާޅުވިއެވެ. ތިޔަކަނބަލުން ޔޫސުފުގެފާނުގެ ކިބައިން ނުބައިކަމަކަށް އެދުނުހިނދު، ކަންވީގޮތަކީ ކޮބައިހެއްޔެވެ؟ އެއުރެން ދެންނެވޫއެވެ. حاش للَّه އެވެ! (ﷲގެ ހުސްތާހިރު ވަންތަކަމާއެވެ!) އެކަލޭގެފާނުގެ ކިބައިގައި އެއްވެސް ނުބައިކަމެއްވާ ކަމަކަށް ތިމަންމެން ދެނެއެއްނެތީމުއެވެ. އަލްޢަޒީޒުގެ އަންހެނުން ބުންޏެވެ. މިހާރު ހައްގު ތެދު ފާޅުވެއްޖެއެވެ. އެކަލޭގެފާނުގެ ކިބައިން ނުބައިކަމަކަށް އެދުނީ، ތިމަންނާއެވެ. އަދި ހަމަކަށަވަރުން، އެކަލޭގެފާނު ވަނީ، ތެދުވެރިންގެ ތެރެއިންނެވެ.","",""],["","","","ذلك ليعلم أني لم أخنه بالغيب وأن الله لا يهدي كيد الخائنين","(ޔޫސުފުގެފާނު ވިދާޅުވިއެވެ.) އެއީ ތިމަން ޣައިބުގައި އޭނާއަށް (އެބަހީ: އަލްޢަޒީޒަށް) ޚިޔާނަތް ތެރި ނުވާކަމާއި، އަދި ޚިޔާނަތް ތެރިންގެ މަކަރުވެރި ރޭވުން ﷲ ފަހިކޮށް ނުދެއްވާނެކަން، އޭނާއަށް އެނގުމަށްޓަކައެވެ.","",""],["","","","وما أبرئ نفسي إن النفس لأمارة بالسوء إلا ما رحم ربي إن ربي غفور رحيم","އަދި ތިމަންކަލޭގެފާނުގެ ނަފްސު ވެސް (ތުހުމަތުން) ބަރީއައެއް ނުކުރައްވަމެވެ. ހަމަކަށަވަރުން، ނަފްސަކީ، ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ރަހުމަތް ލައްވައިފިނަމަ، މެނުވީ، ނުބައިކަންތަކަށް އަބަދުވެސް އަމުރުކުރާ އެއްޗެއްކަން ކަށަވަރެވެ. ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وقال الملك ائتوني به أستخلصه لنفسي فلما كلمه قال إنك اليوم لدينا مكين أمين","ރަސްގެފާނު ވިދާޅުވިއެވެ. އެކަލޭގެފާނު ތިމަންގެ ޚިދުމަތަށް ހާއްސަކުރުމަށްޓަކައި، އެކަލޭގެފާނު ތިމަންގެ ގާތަށް ގެންނާށެވެ! ފަހެ، އެކަލޭގެފާނާ ވާހަކަ ދައްކަވާފައި، އެ ރަސްގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނީ، މިއަދު ތިމަންގެ ގާތުގައި އިތުބާރުކުރެވޭ އަމާނަތް ތެރިޔަކީމުއެވެ.","",""],["","","","قال اجعلني على خزائن الأرض إني حفيظ عليم","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. (މިސްރުގެ) ބިމުގެ ޚަޒާނާތަކުގެ ވެރިޔަކަށް ތިމަން ލައްވާށެވެ! ހަމަކަށަވަރުން، ތިމަންނާއީ (އެއަށް) ރައްކާތެރިވާ (އެއާބެހޭ ކަންތައްތައް) ރަނގަޅަށް ދަންނަ މީޙަކީމެވެ.","",""],["","","","وكذلك مكنا ليوسف في الأرض يتبوأ منها حيث يشاء نصيب برحمتنا من نشاء ولا نضيع أجر المحسنين","އެފަދައިން އެކަލޭގެފާނު ބޭނުންފުޅު ތަނެއްގައި ހުންނެވޭނެގޮތުން ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނު (މިސްރުގެ) ބިމުގައި ބާރުވެރި ކުރެއްވީމެވެ. ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާ ބަޔަކަށް، ތިމަންރަސްކަލާނގެ ރަހުމަތް ލައްވަމެވެ. އަދި އިހްސާން ތެރިންގެ ދަރުމަ، ތިމަންރަސްކަލާނގެ ގެއްލެނި ނުކުރައްވާހުށީމެވެ.","",""],["","","","ولأجر الآخرة خير للذين آمنوا وكانوا يتقون","އަދި ހަމަކަށަވަރުން، އީމާންވެ، ތަގުވާވެރިވެއުޅުނު މީހުންނަށް، އާޚިރަތްގެ ދަރުމައިގެ ހެޔޮކަން މާބޮޑެވެ.","",""],["","","","وجاء إخوة يوسف فدخلوا عليه فعرفهم وهم له منكرون","އަދި ޔޫސުފުގެފާނުގެ އަޚުން އަތުވެއްޖައޫއެވެ. ދެން އެކަލޭގެފާނުގެ އަރިހަށް އެއުރެން ވަދެއްޖައޫއެވެ. އަދި އެކަލޭގެފާނަށް އެއުރެން އެނގިވަޑައިގަތެވެ. ފަހެ، އެއުރެންނަކަށް އެކަލޭގެފާނަކީ ކާކުކަމެއް ނޭނގެތެވެ.","",""],["","","","ولما جهزهم بجهازهم قال ائتوني بأخ لكم من أبيكم ألا ترون أني أوفي الكيل وأنا خير المنزلين","އެއުރެން ބޭނުންވެގެން އައި ސާމާނު ތައްޔާރުކޮށްދެއްވިހިނދު، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. (ތިޔަބައިމީހުން ދޫކޮށްފައި އައި) ތިޔަބައިމީހުންނާ އެއްބަފާ އަޚެއް ތިމަންކަލޭގެފާނުގެ އަރިހަށް ގެންނާށެވެ! ތިމަންކަލޭގެފާނު ހަމަޔަށް މިނެދެއްވާކަމާއި، ތިމަންކަލޭގެފާނީ، އެންމެހެޔޮގޮތުގައި މެހުމާނުންނަށް ކަމޭހިތާ މީހަކުކަން ތިޔަބައިމީހުން ނުދެކެމުހެއްޔެވެ؟","",""],["","","","فإن لم تأتوني به فلا كيل لكم عندي ولا تقربون","ފަހެ، ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނުގެ އަރިހަށް އޭނާ ނުގެނައިނަމަ، ތިމަންކަލޭގެފާނުގެ އަރިހުން ތިޔަބައިމީހުންނަކަށް މިނެދިނުމެއް ނެތެވެ. އަދި ތިޔަބައިމީހުން، ތިމަންކަލޭގެފާނުގެ އަރިހަށް ނާންނާށެވެ!","",""],["","","","قالوا سنراود عنه أباه وإنا لفاعلون","އެއުރެން ދެންނެވޫއެވެ. އޭނާގެ ބައްޕާ އަރިހުން އޭނާ ގެނެވޭތޯ ތިމަންމެން ގަދަމަސައްކަތް ކުރާނަމެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންމެން (އެކަން) ކުރާހުށީމުއެވެ.","",""],["","","","وقال لفتيانه اجعلوا بضاعتهم في رحالهم لعلهم يعرفونها إذا انقلبوا إلى أهلهم لعلهم يرجعون","އެކަލޭގެފާނު ގެންގުޅުއްވާ ކުދިންނަށް ވިދާޅުވިއެވެ. އެއުރެން (އަގަކަށް) ގެނައި މުދާ، އެއުރެންގެ ތަކެތީގެ ތެރެޔަށްލާށެވެ! (އެއީ) އެއުރެންގެ އަހުލުންގެ ގާތަށް އެނބުރިދާހިނދު، އެކަން އެއުރެންނަށް އެނގުމަށްޓަކައެވެ. (އަދި ތިމަންކަލޭގެފާނުގެ އަރިހަށް) އެއުރެން އެނބުރި އާދޭތޯއެވެ.","",""],["","","","فلما رجعوا إلى أبيهم قالوا يا أبانا منع منا الكيل فأرسل معنا أخانا نكتل وإنا له لحافظون","ފަހެ، އެއުރެންގެ ބައްޕާގެ އަރިހަށް އެއުރެން އެނބުރި ދިޔަހިނދު އެއުރެން ދެންނެވޫއެވެ. އޭ އަހުރެމެންގެ ބައްޕާއެވެ! (ތިމަންމެންގެ ކޮއްކޮ ތިމަންމެންނާއެކު ނުފޮނުއްވައިފިނަމަ، ދެން) ތިމަންމެންނަށް މިނެދިނުން މަނާވީއެވެ. ފަހެ، ތިމަންމެންނަށް މިނެދޭތޯ ތިމަންމެންނާއެކު ތިމަންމެންގެ ކޮއްކޮ ފޮނުއްވާށެވެ! އަދި ހަމަކަށަވަރުން، ތިމަންމެން އެކަލޭގެފާނު ބަލަހައްޓައި ރައްކާތެރިކުރާ ހުށީމުއެވެ.","",""],["","","","قال هل آمنكم عليه إلا كما أمنتكم على أخيه من قبل فالله خير حافظا وهو أرحم الراحمين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. މީގެކުރިން އޭނާގެ އަޚު (ޔޫސުފުގެފާނު) އާމެދު ތިޔަބައިމީހުންނަށް އިތުބާރުކުރި ފަދައިން މެނުވީ، އޭނާއާމެދު ތިޔަބައިމީހުންގެ މައްޗަށް ތިމަން އިތުބާރުކުރާނޭ ހެއްޔެވެ؟ ފަހެ، ﷲއީ، ރައްކާތެރިކުރައްވާ، އެންމެ ހެޔޮ ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެއީ ރަހުމަތް ލައްވާ، އެންމެ ރަހުމަތްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ولما فتحوا متاعهم وجدوا بضاعتهم ردت إليهم قالوا يا أبانا ما نبغي هذه بضاعتنا ردت إلينا ونمير أهلنا ونحفظ أخانا ونزداد كيل بعير ذلك كيل يسير","އަދި އެއުރެންގެ ސާމާނު އެއުރެން ހުޅުވިހިނދު، އެއުރެންގެ މުދާ (އޭގެތެރޭގައި) އެއުރެންނަށް ރައްދުކުރެވިފައިވަނިކޮށް ފެނިފައި، އެއުރެން ދެންނެވޫއެވެ. އޭ އަހުރެމެންގެ ބައްޕާއެވެ! (މިއަށްވުރެމޮޅަށް) ތިމަންމެން އެދޭނީ ކޮންކަމެއްހެއްޔެވެ؟ މިހިރީ ތިމަންމެންގެ މުދާ ތިމަންމެންނަށް ރައްދުކުރެވިފައެވެ. އަދި ތިމަންމެންގެ އަހުލުންނަށް (އިތުރަށް) ކާބޯތަކެތި ގެނެސްދީ، އަދި ތިމަންމެންގެ ކޮއްކޮ ރައްކާތެރި ކުރާހުށީމުއެވެ. އަދި ޖަމަލަކަށް އެރުވޭތަކެތި އިތުރުކުރާނޫއެވެ. އެއީ މިނެދެވޭ މަދު އެތިކޮޅެކެވެ.","",""],["","","","قال لن أرسله معكم حتى تؤتون موثقا من الله لتأتنني به إلا أن يحاط بكم فلما آتوه موثقهم قال الله على ما نقول وكيل","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންގެ މައްޗަށް އަދާވަތް ތެރިންގެ ބަޔަކު ގަދަވެއްޖެހިނދަކު މެނުވީ، އޭނާ އަނބުރާ ތިމަންކަލޭގެފާނުގެ އަރިހަށް ގެނެސްދޭންކަމަށް، ﷲގެ ހަޒުރަތު ންވާ އަހުދެއް ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނަށް ގެނެސްދީފުމަށް ދާނދެން ތިޔަބައިމީހުންނާއެކު އޭނާއެއް ނުފޮނުއްވާ ހުށީމެވެ. ފަހެ، އެއުރެންގެ ކަށަވަރުވެގެންވާ އަހުދުގެ ބަސް ގެނެސްގަތްހިނދު، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިމަންމެން މިބުނާ އެއްޗަކަށް، ﷲ ހެކިވެވޮޑިގެންވާނެތެވެ.","",""],["","","","وقال يا بني لا تدخلوا من باب واحد وادخلوا من أبواب متفرقة وما أغني عنكم من الله من شيء إن الحكم إلا لله عليه توكلت وعليه فليتوكل المتوكلون","އަދި އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ދަރިންނޭވެ! ތިޔަބައިމީހުން (އެތަނަށްގޮސް) އެއްދޮރޯއްޓަކުން ނުވަންނާށެވެ! އަދި ތަފާތު ދޮރޯށިތަކަކުން ވަންނާށެވެ! އަދި ﷲގެ ހަޒުރަތުން ތިޔަބައިމީހުންނަށް އެއްވެސްކަމެއް ތިމަންނާއަކަށް ފުއްދައެއް ނުދެވޭނެތެވެ. ﷲއަށް މެނުވީ ހުކުމްކުރެއްވުމެއް ނެތެވެ. ތިމަންކަލޭގެފާނު ވަކީލުކުރައްވަނީ، އެކަލާނގެއަށެވެ. އަދި ވަކީލުކުރާމީހުން ހަމައެކަނި އެކަލާނގެއަށް ވަކީލުކުރާހުށިކަމެވެ!","",""],["","","","ولما دخلوا من حيث أمرهم أبوهم ما كان يغني عنهم من الله من شيء إلا حاجة في نفس يعقوب قضاها وإنه لذو علم لما علمناه ولكن أكثر الناس لا يعلمون","އަދި އެއުރެންގެ ބައްޕާ އަމުރުކުރެއްވިގޮތަށް، އެއުރެންގޮސް ވަންހިނދު އެކަލޭގެފާނަކަށް ﷲގެ ހަޒުރަތުން އެއްވެސްކަމެއް އެއުރެންނަކަށް ފުއްދައެއް ނުދެއްވުނެވެ. ހަމައެކަނި، ޔައުގޫބުގެފާނުގެ ހިތްޕުޅުގައިއޮތް ބޭނުމެއް މެނުވީ ނުފުދެތެވެ. (އެއީ ޔައުގޫބުގެފާނު ވިދާޅުވިގޮތަށް އެއުރެން އެކަން ކުރުމެވެ.) އަދި ހަމަކަށަވަރުން، އެކަލޭގެފާނީ، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް އުނގަންނައިދެއްވި އެއްޗެއް ރަނގަޅަށް ދެނެހުންނެވި ބޭކަލެކެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުން (އެކަމެއް) ނުދަނެތެވެ.","",""],["","","","ولما دخلوا على يوسف آوى إليه أخاه قال إني أنا أخوك فلا تبتئس بما كانوا يعملون","އަދި ޔޫސުފުގެފާނުގެ އަރިހަށް އެއުރެން ވަނުމުން، އެކަލޭގެފާނުގެ އަޚު އެކަލޭގެފާނުގެ އަރިހަށް ގެންދަވައި ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިމަންނާއީ، ތިބާގެ އަޚާއެވެ. ފަހެ، އެއުރެން ކޮށްއުޅުނު ކަންތަކާމެދު ތިބާ ހިތާމަނުކުރާށެވެ!","",""],["","","","فلما جهزهم بجهازهم جعل السقاية في رحل أخيه ثم أذن مؤذن أيتها العير إنكم لسارقون","ފަހެ، އެކަލޭގެފާނު އެއުރެންގެ ސާމާނު ތައްޔާރުކޮށްދެއްވިހިނދު (މިނެހެދުމަށް ގެންގުޅޭ) ސިގާޔަތް، އޭނާގެ އަޚުގެ ތަކެތީގެ ތެރެއަށް ލެއްވިއެވެ. ދެން ގޮވައި އަންގާ މީހަކު ގޮވިއެވެ. އޭ ގާފިލާގެ މީހުންނޭވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނީ، ވައްކަންކުރާ ބަޔެކެވެ.","",""],["","","","قالوا وأقبلوا عليهم ماذا تفقدون","އެއުރެން އެއުރެންނާ ކުރިމަތިލައި އައިސް ބުނެފޫއެވެ. ތިޔަބައިމީހުން ގެއްލިގެންތިޔަ އުޅެނީ ކޮންއެއްޗެއް ހެއްޔެވެ؟","",""],["","","","قالوا نفقد صواع الملك ولمن جاء به حمل بعير وأنا به زعيم","އެއުރެން ބުނެފޫއެވެ. ތިމަންމެން ގެއްލިގެން މިއުޅެނީ، ރަސްގެފާނުގެ ނާޅިއެވެ. އަދި އެ ގެނެސްދިން މީހަކަށް އޮތް އިނާމަކީ، ޖަމަލަކަށް އެރުވޭހާ ތަކެއްޗެވެ. އެކަމަށް އަހަރެން ޖާމިނުވެގެންވަމެވެ.","",""],["","","","قالوا تالله لقد علمتم ما جئنا لنفسد في الأرض وما كنا سارقين","އެއުރެން ދެންނެވޫއެވެ. ﷲ ގަންދީ ބުނަމުއެވެ. ތިމަންމެންއައީ ބިމުގައި ފަސާދަކުރުމަށް ނޫންކަން ތިޔަބައިމީހުންނަށް އެނގިފައިވާނެކަން ކަށަވަރެވެ. އަދި ވައްކަންކުރާ ބަޔަކު ކަމުގައި ތިމަންމެން ނުވަމުއެވެ.","",""],["","","","قالوا فما جزاؤه إن كنتم كاذبين","އެއުރެން ބުނެފޫއެވެ. ތިޔަބައިމީހުން ދޮގުހަދާކަމަށްވާނަމަ، ފަހެ، އެކަމުގެ (އެބަހީ: މިނާއެތި ވަގަށްނެގުމުގެ) ޖަޒާއަކީ ކޮބައިހެއްޔެވެ؟","",""],["","","","قالوا جزاؤه من وجد في رحله فهو جزاؤه كذلك نجزي الظالمين","އެއުރެން ބުނެފޫއެވެ. އެކަމުގެ ޖަޒާއަކީ، އެމީހެއްގެ ތަކެތީގެ ތެރެއިން އެ މިނާއެތި ފެނުނު މީހެކެވެ. ފަހެ، އޭނާ އެއީ އެކަމުގެ ޖަޒާއެވެ. (އެބަހީ: ޖަޒާދިނުމަށްޓަކައި އެމީހަކު ހިފެހެއްޓުމެވެ.) އަނިޔާވެރިންނަށް ތިމަންރަސްކަލާނގެ ޖަޒާދެއްވަނީ، އެފަދައިންނެވެ.","",""],["","","","فبدأ بأوعيتهم قبل وعاء أخيه ثم استخرجها من وعاء أخيه كذلك كدنا ليوسف ما كان ليأخذ أخاه في دين الملك إلا أن يشاء الله نرفع درجات من نشاء وفوق كل ذي علم عليم","ފަހެ، އެކަލޭގެފާނުގެ އަޚާގެ ތަކެތި ހޯދުމުގެ ކުރިން، އެއުރެންގެ ތަކެތި ހޯދަންފެށިއެވެ. ދެން އެކަލޭގެފާނުގެ އަޚާގެ ތަކެތީގެ ތެރެއިން، އެ މިނާއެތި ނެރުނެވެ. އެގޮތަށް ޔޫސުފުގެފާނަށްޓަކައި، ތިމަންރަސްކަލާނގެ (އެކަންތައް) ރޭއްވެވީމެވެ. ﷲ އިރާދަކުރެއްވުމާނުލައި، ރަސްގެފާނުގެ އާދަޔާ އެއްގޮތަށް އެކަލޭގެފާނަކަށް، އޭނާގެ އަޚާ އަތަކު ނުލެއްވުނީހެވެ. ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާ ބަޔަކު، ދަރަޖަ މަތިވެރިކުރައްވަމެވެ. އަދި ކޮންމެ އިލްމުވެރިޔެއްގެ މައްޗަށް (ހުރިހާކަމެއް) މޮޅަށް ދެނެވޮޑިގެންވާ ކަލާނގެ ވޮޑިގެންވެއެވެ.","",""],["","","","قالوا إن يسرق فقد سرق أخ له من قبل فأسرها يوسف في نفسه ولم يبدها لهم قال أنتم شر مكانا والله أعلم بما تصفون","އެއުރެން ބުނެފޫއެވެ. އޭނާ ވައްކަންކުރިކަމަށްވާނަމަ، މީގެކުރިން އޭނާގެ އަޚަކުވެސްވަނީ ވައްކަންކޮށްފައެވެ. ފަހެ، ޔޫސުފުގެފާނު، އެކަލޭގެފާނުގެ ހިތްޕުޅުގައި އެ ބަސް ސިއްރުކުރެއްވިއެވެ. އަދި އެއުރެންނަށް އެކަން ފާޅެއްނުކުރައްވަތެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންގެ ދަރަޖަ އެއަށްވުރެ މާނުބައެވެ. އަދި ތިޔަބައިމީހުން ސިފަކޮށް ބުނާއެއްޗެއް ﷲ ދެނެވޮޑިގަތުން ބޮޑެވެ.","",""],["","","","قالوا يا أيها العزيز إن له أبا شيخا كبيرا فخذ أحدنا مكانه إنا نراك من المحسنين","އެއުރެން ދެންނެވޫއެވެ. އޭ އަލްޢަޒީޒެވެ! ހަމަކަށަވަރުން، އޭނާގެ ގަދަރުވެރި މުސްކުޅި ބައްޕައެއްވެއެވެ. ފަހެ، ތިމަންމެންގެ ތެރެއިން އެކަކު އޭނާގެ ބަދަލުގައި ހިފަހައްޓަވާށެވެ! ހަމަކަށަވަރުން، ތިމަންމެން ކަލޭގެފާނު ދެކެނީ، އިހްސާން ތެރިންގެ ތެރެއިންނެވެ.","",""],["","","","قال معاذ الله أن نأخذ إلا من وجدنا متاعنا عنده إنا إذا لظالمون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. [معاذ ﷲ] އެވެ. (އެބަހީ: ﷲގެ ރައްކާތެރިކަމަށް އެދެމެވެ.) އެމީހެއްގެ އަތުގައި ތިމަންމެންގެ ތަކެތި ހުއްޓައި ފެނުނު މީހަކު މެނުވީ، ތިމަންމެން ހިފެހެއްޓުމުން ދުރުވެ، ރައްކާތެރިވުން އެދެމެވެ. އެހެންވެއްޖެނަމަ، ހަމަކަށަވަރުން، ތިމަންމެންވާހުށީ އަނިޔާވެރިން ކަމުގައެވެ.","",""],["","","","فلما استيأسوا منه خلصوا نجيا قال كبيرهم ألم تعلموا أن أباكم قد أخذ عليكم موثقا من الله ومن قبل ما فرطتم في يوسف فلن أبرح الأرض حتى يأذن لي أبي أو يحكم الله لي وهو خير الحاكمين","ފަހެ، އެއުރެން އެކަލޭގެފާނުގެ ކިބައިން އުއްމީދު ކެނޑުނުހިނދު، އެއުރެން އެކަހެރިވެ ސައްލާކުރޫއެވެ. އެއުރެންގެ ބޮޑަކަށްހުރި މީހާ ބުންޏެވެ. ތިޔަބައިމީހުންގެ މައްޗަށް ތިޔަބައިމީހުންގެ ބައްޕާ، ﷲގެ ހަޒުރަތުން އަހުދު ކަށަވަރު ހިއްޕަވާފައިވާކަމާއި، އޭގެކުރިން ޔޫސުފުގެފާނާމެދު ތިޔަބައިމީހުން ފަރުވާކުޑަކޮށްފައިވާކަން، ތިޔަބައިމީހުންނަކަށް ނޭނގޭހެއްޔެވެ؟ ފަހެ، ތިމަންގެ ބައްޕާ ތިމަންނައަށް އިޒުނަ ދެއްވައިފުމަށްދާނދެން، ނުވަތަ ﷲ ތިމަންގެ މައްޗަށް ނިޔާކުރައްވައިފުމަށްދާނދެން ތިމަން (މިސްރުގެ) ބިން ދޫކޮށެއް ނުލާހުށީމެވެ. އަދި އެކަލާނގެއީ ހުކުމްކުރައްވާ އެންމެ ހެޔޮ ރަސްކަލާނގެއެވެ.","",""],["","","","ارجعوا إلى أبيكم فقولوا يا أبانا إن ابنك سرق وما شهدنا إلا بما علمنا وما كنا للغيب حافظين","ތިޔަބައިމީހުން އެނބުރި ތިޔަބައިމީހުންގެ ބައްޕާ އަރިހަށްގޮސް ދަންނަވާށެވެ! އޭ އަހުރެމެންގެ ބައްޕާއެވެ! ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ދަރިކަލުން ވައްކަންކޮށްފިއެވެ. އަދި ތިމަންމެންނަށް އެނގިފައިވާކަމަކަށް މެނުވީ، ތިމަންމެން ހެތްކެއް ނުވަމުއެވެ. އަދި ޣައިބު ގައިވާ ކަންތައް ދަންނަބަޔަކު ކަމުގައި ތިމަންމެން ނުވަމުއެވެ.","",""],["","","","واسأل القرية التي كنا فيها والعير التي أقبلنا فيها وإنا لصادقون","އަދި ތިމަންމެންގޮސް ތިބި ރަށުގެ މީހުންނާ، އަދި ތިމަންމެން އޭގައި ދަތުރުކޮށްފައި އައި ގާފިލާގެ މީހުންނާ ސުވާލުކުރައްވާށެވެ! އަދި ހަމަކަށަވަރުން، ތިމަންމެންނީ ތެދުބުނާ ބަޔަކީމުއެވެ.","",""],["","","","قال بل سولت لكم أنفسكم أمرا فصبر جميل عسى الله أن يأتيني بهم جميعا إنه هو العليم الحكيم","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަދި ކިއެއްތަ! ތިޔަބައިމީހުންގެ ނަފްސުތައް ތިޔަބައިމީހުންނަށް (ނުބައި) ކަމެއް ޒީނަތްތެރިކޮށްދިނީއެވެ. ފަހެ، ދެން އޮތީ ރިވެތިވެގެންވާ ކެތްކުރުމެކެވެ. ﷲ އެ އެންމެން ތިމަންކަލޭގެފާނުގެ އަރިހަށް ގެނެސްދެއްވައިފާށިއެވެ! ހަމަކަށަވަރުން، އެކަލާނގެއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وتولى عنهم وقال يا أسفى على يوسف وابيضت عيناه من الحزن فهو كظيم","އަދި އެކަލޭގެފާނު އެއުރެންނާ އެއްކިބާވެ ވަޑައިގަތެވެ. އަދި ވިދާޅުވިއެވެ. ޔޫސުފުގެފާނުގެ މައްޗަށް އަހުރެން ކުރާ ހިތާމައެއްގެ ބޮޑުކަމާއެވެ! އަދި ހިތާމައިގެ ސަބަބުން، އެކަލޭގެފާނުގެ ލޯފުޅު ހުދުވެގެންދިޔައެވެ. ފަހެ، އެކަލޭގެފާނީ، ހިތާމަފާޅު ނުކުރައްވައި، ހިފަހައްޓަވާ ބޭކަލެކެވެ.","",""],["","","","قالوا تالله تفتأ تذكر يوسف حتى تكون حرضا أو تكون من الهالكين","އެއުރެން ދެންނެވޫއެވެ. ﷲ ގަންދީ ހުވާކުރަމެވެ. ކަލޭގެފާނު ބަލިޙާލު ބޮޑުވެއްޖެއުމަށްދާނދެން، ނުވަތަ މަރުވެފައިވާ މީހުންގެ ތެރެއިން ހިމެނިއްޖައުމަށްދާނދެން، ޔޫސުފުގެފާނުމަތިން ހަނދުމަކުރެއްވުމުގައި ކަލޭގެފާނު ފިލާވަޑައިނުގަންނަވަމުއެވެ.","",""],["","","","قال إنما أشكو بثي وحزني إلى الله وأعلم من الله ما لا تعلمون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިމަންކަލޭގެފާނުގެ މޮޅިޔާއި، ހިތާމައިގެ ޝާކުވާ ދަންނަވާކަން ކަށަވަރީ، ހަމައެކަނި ﷲއަށެވެ. އަދި ތިޔަބައިމީހުންނަށް ނޭނގޭ ކަންތައްތަކެއް، ﷲގެ ހަޒުރަތުން ތިމަންކަލޭގެފާނަށް އެނގިވަޑައިގަނެއެވެ.","",""],["","","","يا بني اذهبوا فتحسسوا من يوسف وأخيه ولا تيأسوا من روح الله إنه لا ييأس من روح الله إلا القوم الكافرون","އޭ އަހުރެންގެ ދަރިންނޭވެ! ޔޫސުފުގެފާނާއި، އޭނާގެ އަޚާގެ ޚަބަރެއްވޭތޯ ތިޔަބައިމީހުން ދާށެވެ! އަދި ﷲގެ ރަހުމަތުން ތިޔަބައިމީހުން އުއްމީދު ކަނޑައިނުލާށެވެ! (ހަމަކަށަވަރުން، ކާފިރު ވިމީހުން މެނުވީ، ﷲގެ ރަހުމަތުން އުއްމީދު ކަނޑައެއް ނުލާނެތެވެ.)","",""],["","","","فلما دخلوا عليه قالوا يا أيها العزيز مسنا وأهلنا الضر وجئنا ببضاعة مزجاة فأوف لنا الكيل وتصدق علينا إن الله يجزي المتصدقين","ފަހެ، އެއުރެން އެކަލޭގެފާނުގެ އަރިހަށް ވަންހިނދު، އެއުރެން ދެންނެވޫއެވެ. އޭ އަލްޢަޒީޒެވެ! ތިމަންމެންނަށާއި، ތިމަންމެންގެ އަހުލުވެރިންނަށް ތަދުމަޑުކަން ޖެހިއްޖެއެވެ. ތިމަންމެންއައީ، ދެރަ މުދަލަކާއިގެންނެވެ. ފަހެ، ތިމަންމެންނަށް ފުރިހަމަގޮތުގައި މިނެދެއްވައި، ތިމަންމެންނަށް ސަދަގާތްކުރައްވާށެވެ! ހަމަކަށަވަރުން، ސަދަގާތްކުރާ މީހުންނަށް ﷲ (ހެޔޮ) ޖަޒާދެއްވާނެތެވެ.","",""],["","","","قال هل علمتم ما فعلتم بيوسف وأخيه إذ أنتم جاهلون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންނަށް ނޭނގިތިބި ޙާލު، ޔޫސުފުގެފާނަށާއި، އެކަލޭގެފާނުގެ އަޚާއަށް ތިޔަބައިމީހުން ކުރިކަންތައް ތިޔަބައިމީހުން ދެނެތިބީމުހެއްޔެވެ؟","",""],["","","","قالوا أإنك لأنت يوسف قال أنا يوسف وهذا أخي قد من الله علينا إنه من يتق ويصبر فإن الله لا يضيع أجر المحسنين","އެއުރެން ދެންނެވޫއެވެ. ހަމަކަށަވަރުން، ތިޔައީ ޔޫސުފުގެފާނު ތޯއެވެ؟ އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަހުރެންނަކީ، ޔޫސުފުގެފާނީމެވެ. އަދި މިއީ ތިމަންކަލޭގެފާނުގެ އަޚާއެވެ. ހަމަކަށަވަރުން، ﷲ ތިމަންމެންގެ މައްޗަށް ދަރުމަވަންތަވެވޮޑިގެންފިއެވެ. ހަމަކަށަވަރުން، ތަގުވާވެރިވެ ކެތްތެރިވާމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އިހްސާން ތެރިންގެ ދަރުމަ، ﷲގެއްލެނި ނުކުރައްވާނެތެވެ.","",""],["","","","قالوا تالله لقد آثرك الله علينا وإن كنا لخاطئين","އެއުރެން ދެންނެވޫއެވެ. ﷲ ގަންދީ ބުނަމުއެވެ. ހަމަކަށަވަރުން، ﷲ ތިމަންމެންގެ މައްޗަށް ކަލޭގެފާނު މަތިވެރިކުރައްވައި، މާތްކުރެއްވިއެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންމެންވަނީ، ކުށްވެރިން ކަމުގައެވެ.","",""],["","","","قال لا تثريب عليكم اليوم يغفر الله لكم وهو أرحم الراحمين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. މިއަދު ތިޔަބައިމީހުންގެ މައްޗަކަށް މަލާމާތެއް ދެރަބަހެއް ނެތެވެ. ތިޔަބައިމީހުންނަށް ﷲ ފާފަފުއްސަވާށިއެވެ! އަދި އެކަލާނގެއީ، ރަހުމަތް ލައްވާ އެންމެ ރަހުމަތްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","اذهبوا بقميصي هذا فألقوه على وجه أبي يأت بصيرا وأتوني بأهلكم أجمعين","ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނުގެ މި ގަމީސްކޮޅާއިގެން ދާށެވެ! އަދި ތިމަންކަލޭގެފާނުގެ ބައްޕާގެ މޫނުފުޅުމައްޗަށް އެ ގަމީސްކޮޅު އެއްލާށެވެ! އޭރުން ލޮލަށް ފެންނަމީހަކު ކަމުގައި އެކަލޭގެފާނު އަލުން ވެވަޑައިގެންފާނެތެވެ. އަދި ތިޔަބައިމީހުންގެ އަހުލުވެރިންގެ އެންމެން ގޮވައިގެން ތިމަންކަލޭގެފާނުގެ އަރިހަށް އަންނާށެވެ!","",""],["","","","ولما فصلت العير قال أبوهم إني لأجد ريح يوسف لولا أن تفندون","އެ ގާފިލާ (ރަށުން) ވަކިވިހިނދު، އެއުރެންގެ ބައްޕާ ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނަށް ޔޫސުފުގެފާނުގެ ވަސް އެބަދުވައެވެ. ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނު މޮޔައަކަށް ނަހަދާނެނަމައެވެ.","",""],["","","","قالوا تالله إنك لفي ضلالك القديم","އެއުރެން ދެންނެވޫއެވެ. ﷲ ގަންދީ ބުނަމުއެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުވަނީ، ކުރިންވެސް ކަލޭގެފާނު ހުންނެވި ކުށް ޚިޔާލު ގައިކަން ކަށަވަރެވެ.","",""],["","","","فلما أن جاء البشير ألقاه على وجهه فارتد بصيرا قال ألم أقل لكم إني أعلم من الله ما لا تعلمون","ފަހެ، އުފާވެރިކަމުގެ ޚަބަރު ދޭމީހާ އައިސް އެކަލޭގެފާނުގެ މޫނުފުޅުމައްޗަށް އެ ގަމީސްކޮޅު އެއްލިއެވެ. ފަހެ، އެހިނދު ލޮލަށް ފެންނަމީހަކު ކަމުގައި އަލުން އެކަލޭގެފާނު ވެވަޑައިގެންފިއެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންނަށް ނޭނގޭ ކަންތައްތަކެއް ހަމަކަށަވަރުން، ﷲގެ ހަޒުރަތުން ތިމަންކަލޭގެފާނަށް އެނގިވަޑައިގަންނަވާކަމަށް، ތިމަންކަލޭގެފާނު ވިދާޅެއް ނުވަންހެއްޔެވެ؟","",""],["","","","قالوا يا أبانا استغفر لنا ذنوبنا إنا كنا خاطئين","އެއުރެން ދެންނެވޫއެވެ. އޭ އަހުރެމެންގެ ބައްޕާއެވެ! ތިމަންމެންނަށް ތިމަންމެންގެ ފާފަތައް ފުއްސެވުމަށް، ކަލޭގެފާނު ދުއާ ކޮށްދެއްވާށެވެ! ހަމަކަށަވަރުން، ތިމަންމެންވީ ކުށްވެރިން ކަމުގައެވެ.","",""],["","","","قال سوف أستغفر لكم ربي إنه هو الغفور الرحيم","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންނަށް ފާފަފުއްސެވުމަށްއެދި ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ދުއާކުރައްވާހުށީމެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","فلما دخلوا على يوسف آوى إليه أبويه وقال ادخلوا مصر إن شاء الله آمنين","ފަހެ، އެއުރެން (އެންމެން) ޔޫސުފުގެފާނުގެ އަރިހަށް (ގޮސް) ވަންހިނދު، އެކަލޭގެފާނުގެ މައިންބަފައިން އެކަލޭގެފާނުގެ އަރިހަށް ލަފައިލެއްވިއެވެ. އަދި ވިދާޅުވިއެވެ. ﷲގެ އިރާދަފުޅާއެކު، އަމާންކަން ލިބިގެންވާ ޙާލުގައި، މިޞްރަށް ވެދެވަޑައިގަންނަވާށެވެ!","",""],["","","","ورفع أبويه على العرش وخروا له سجدا وقال يا أبت هذا تأويل رؤياي من قبل قد جعلها ربي حقا وقد أحسن بي إذ أخرجني من السجن وجاء بكم من البدو من بعد أن نزغ الشيطان بيني وبين إخوتي إن ربي لطيف لما يشاء إنه هو العليم الحكيم","އަދި ޔޫސުފުގެފާނު އެކަލޭގެފާނުގެ މައިބަފައިކަލުން ތަޚުތަށް އުފުއްލެވިއެވެ. އަދި އެ އެންމެން އެކަލޭގެފާނަށް ކުރުނީސްކޮށް، ސަޖިދަށް ތިރިވެގަތޫއެވެ. އަދި އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ ބައްޕާއެވެ! ކުރިން ތިމަންނާއަށް ފެނިވަޑައިގަތް ހުވަފެނުގެ މާނައަކީ، މިއީއެވެ. ހަމަކަށަވަރުން، ތިމަންގެ ވެރިރަސްކަލާނގެ، އެ ހުވަފެން ހައްގު ތެދެއް ކަމުގައި ލެއްވިއެވެ. އަދި ތިމަން ޖަލުން ނެރުއްވުމާއި، ތިމަންނާއާއި، ތިމަންގެ އަޚުންނާ ދެމެދު ޝައިތާނާ ނުބައިކޮށްފުމަށް ފަހުގައި، ބަދަވީންގެ ދިރިއުޅުމުން ތިޔަބައިމީހުން ގެންނެވި ކަމާއި، މިހުރިހާ ކަމެއްގައި ތިމަންނާއަށް އެކަލާނގެ ރަނގަޅުގޮތް މެދުވެރިކުރެއްވިއެވެ. ހަމަކަށަވަރުން، ތިމަންގެ ވެރިރަސްކަލާނގެއީ، އެކަލާނގެ އިރާދަކުރައްވާ ކަމަކަށް އޯގާވަންތަ ރަސްކަލާނގެއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","رب قد آتيتني من الملك وعلمتني من تأويل الأحاديث فاطر السماوات والأرض أنت وليي في الدنيا والآخرة توفني مسلما وألحقني بالصالحين","އަޅުގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެ ތިމަންއަޅާއަށް ވެރިކަން ދެއްވީމުއެވެ. އަދި ހުވަފެންތައް މާނަކުރަން ދަސްކޮށްދެއްވީމުއެވެ. އިސްވެދިޔަ މިސާލަކާނުލައި، އުޑުތަކާއި، ބިން ހެއްދެވި ރަސްކަލާކޮ! ދުނިޔެއާއި، އާޚިރަތުގައި މިއަޅާގެ އެހީތެރިއަކީ، އިބަރަސްކަލާނގެއެވެ. މުސްލިމެއްގެ ގޮތުގައި މިއަޅާ މަރުގަންނަވާނދޭވެ! އަދި ސާލިހުންގެ ތެރެއިން މިއަޅާ ލައްވާނދޭވެ!","",""],["","","","ذلك من أنباء الغيب نوحيه إليك وما كنت لديهم إذ أجمعوا أمرهم وهم يمكرون","އެއީ ޣައިބުގެ ޚަބަރުތަކުގެ ތެރެއިން، ކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ ވަހީކުރައްވާ ޚަބަރު ތަކެވެ. އަދި އެއުރެން މަކަރުވެރި ރޭވުންތައް ރާވާ ޙާލު، އެއުރެންގެ ކަންތައްތަކަށް އެއްބަސްވިއިރަކު، އެއުރެންގެ ގާތުގައި ކަލޭގެފާނު ވަޑައިގެން ނުވަމުއެވެ.","",""],["","","","وما أكثر الناس ولو حرصت بمؤمنين","އަދި ކަލޭގެފާނު ކިތަންމެވަރަކަށް ޝޫގުވެރިވެވަޑައިގަތަސް، މީސްތަކުންކުރެ ގިނަމީހުން އީމާންވާ ބަޔަކު ކަމުގައެއް ނުވެތެވެ.","",""],["","","","وما تسألهم عليه من أجر إن هو إلا ذكر للعالمين","އަދި އެ ގުރްއާނަށްޓަކައި، ކަލޭގެފާނު އެއުރެންގެ ކިބައިން އުޖޫރައަކަށް އެދިވަޑައެއް ނުގަންނަވަމުއެވެ. އާލަމްތަކަށް ހަނދާންކޮށްދިނުމެއްކަމުގައި މެނުވީ، އެ ގުރްއާން ނުވެތެވެ.","",""],["","","","وكأين من آية في السماوات والأرض يمرون عليها وهم عنها معرضون","އުޑުތަކާއި، ބިމުގައިވާ ހެކިތަކުގެ ތެރެއިން، އެއުރެންނަށް ފެނި، ކުރިމަތިވާ، އަދި އެ ހެކިތަކުން އެއުރެން އެއްކިބާވެ، އެއާމެދު ފިކުރުނުކުރާ، ކިތައްކިތައް ހެކި ވޭހެއްޔެވެ؟","",""],["","","","وما يؤمن أكثرهم بالله إلا وهم مشركون","އަދި އެއުރެންކުރެ ގިނަމީހުން، ޝަރީކުކުރާ ބަޔަކުކަމުގައިވާ ޙާލުގައި މެނުވީ، ﷲއަށް އީމާނެއް ނުވެތެވެ.","",""],["","","","أفأمنوا أن تأتيهم غاشية من عذاب الله أو تأتيهم الساعة بغتة وهم لا يشعرون","ފަހެ، ﷲގެ އަޒާބުގެ ތެރެއިން ކޯފާއެއް އެއުރެންގެ މައްޗަށް އަތުވެދާނެކަމުގެ ބިރެއް، ނުވަތަ އެއުރެން ނުދެނެތިއްބައި، ކުއްލިއަކަށް ގިޔާމަތްގެ ވަގުތު އެއުރެންނަށް އަތުވެދާނޭކަމުގެ ބިރެއްނެތި، އެއުރެން އަމާންކަން ލިބިގެން ތިބީހެއްޔެވެ؟","",""],["","","","قل هذه سبيلي أدعو إلى الله على بصيرة أنا ومن اتبعني وسبحان الله وما أنا من المشركين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! މިއީ ތިމަންކަލޭގެފާނުގެ މަގެވެ. ތިމަންކަލޭގެފާނާއި، ތިމަންކަލޭގެފާނަށް ތަބާވި މީހުން، ﷲގެ ފަރާތަށް ގޮވައިލައްވަނީ، އަލިވެގެންވާ ދަލީލާއެކުގައެވެ. އަދި ﷲގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! އަދި ޝަރީކުކުރާ މީހުންގެ ތެރެއިން ތިމަންކަލޭގެފާނު ނުވަމެވެ.","",""],["","","","وما أرسلنا من قبلك إلا رجالا نوحي إليهم من أهل القرى أفلم يسيروا في الأرض فينظروا كيف كان عاقبة الذين من قبلهم ولدار الآخرة خير للذين اتقوا أفلا تعقلون","އަދި ކަލޭގެފާނުގެ ކުރިންވެސް، ރަށްތަކުގެ އަހުލުވެރިންގެ ތެރެއިން އެބަޔަކަށް ތިމަންރަސްކަލާނގެ ވަހީ އިއްވަވައި، ރަސޫލުކަމާއިގެން ފިރިހެނުން މެނުވީ ނުފޮނުއްވަމެވެ. ފަހެ، ބިމުގައި ދަތުރުފަތުރުކޮށް އެއުރެންގެ ކުރިން އުޅުނު މީހުންގެ ނިމުންވީ ކޮންފަދައަކުންކަން، އެއުރެން ނުބަލަނީ ހެއްޔެވެ؟ އަދި ހަމަކަށަވަރުން، ތަގުވާވެރިވި މީހުންނަށް، އާޚިރަތްގެ ގޮވަތި، ހެޔޮކަން ބޮޑެވެ. ފަހެ، ތިޔަބައިމީހުންނަކަށް ނުވިސްނޭހެއްޔެވެ؟","",""],["","","","حتى إذا استيأس الرسل وظنوا أنهم قد كذبوا جاءهم نصرنا فنجي من نشاء ولا يرد بأسنا عن القوم المجرمين","(މެދުވެރިވާ ދުއްތުރާތަކުގެ ސަބަބުން) ރަސޫލުންގެ އުއްމީދު ކެނޑި، އެބޭކަލުން ދޮގުކުރެވުނީކަމަށް އެބޭކަލުންނަށް ހީވެދާހިނދު، ތިމަންރަސްކަލާނގެ ނަސްރު، އެބޭކަލުންނަށް އަތުވެދެއެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާ ބަޔަކު ސަލާމަތްކުރައްވަމެވެ. އަދި ކުށްވެރިވި މީހުންގެ ކިބައިން، ތިމަންރަސްކަލާނގެ އަޒާބު އަނބުރާ ރައްދުނުކުރެވޭ ހުށްޓެވެ.","",""],["","","","لقد كان في قصصهم عبرة لأولي الألباب ما كان حديثا يفترى ولكن تصديق الذي بين يديه وتفصيل كل شيء وهدى ورحمة لقوم يؤمنون","ހަމަކަށަވަރުން، އެއުރެންގެ ވާހަކަތަކުގައި، ބުއްދީގެ އަހުލުވެރިންނަށް އިބްރަތެއް ވާކަން ކަށަވަރެވެ. އެ ގުރްއާނަކީ، ހަދައިގެން އުފެއްދޭ ވާހަކަތަކެއްނޫނެވެ. އެހެނެއްކަމަކު، އެއީ އޭގެކުރިން ބާވައިލެއްވި ފޮތްތައް ތެދުކުރާ، އަދި ހުރިހާކަމެއް ތަފްޞީލު ކޮށްދޭ، އަދި އީމާންވާ ބަޔަކަށް ހިދާޔަތެއް ކަމުގައްޔާއި، ރަހުމަތެއް ކަމުގައިވާ ފޮތެވެ.","",""],["","","","بسم الله الرحمن الرحيم المر تلك آيات الكتاب والذي أنزل إليك من ربك الحق ولكن أكثر الناس لا يؤمنون","ا ل م ر (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.) މިއީ ފޮތުގެ އާޔަތް ތަކެވެ. އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ކަލޭގެފާނަށް ބާވައިލެއްވި ހައްގު ތެދެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުން (އެ ފޮތަކަށް) އީމާނެއް ނުވެތެވެ.","",""],["","","","الله الذي رفع السماوات بغير عمد ترونها ثم استوى على العرش وسخر الشمس والقمر كل يجري لأجل مسمى يدبر الأمر يفصل الآيات لعلكم بلقاء ربكم توقنون","ﷲއީ، ތިޔަބައިމީހުންނަށް ފެންނަ ތަނބުތަކަކާ ނުލައި، އުޑުތައް އުފުއްލެވި ރަސްކަލާނގެއެވެ. ދެން ޢަރްޝުގެ މައްޗަށް އެކަލާނގެ އިސްތިވާ ވެވޮޑިގަތެވެ. އަދި އިރާއި، ހަނދު ޚިދުމަތް ތެރި ކުރެއްވިއެވެ. (އެއިން) ކޮންމެ އެއްޗެއް ކަނޑައެޅިގެންވާ މުއްދަތަކަށް ހިނގަހިނގާ ހުރެތެވެ. ހުރިހާ ކަމެއް އެކަލާނގެ ތަދްބީރުކުރައްވަތެވެ. އާޔަތްތައް ތަފްޞީލު ކޮށްދެއްވަތެވެ. (އެއީ) ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއާ ބައްދަލުވާނޭކަން، ތިޔަބައިމީހުން ޔަގީންކުރުމަށްޓަކައެވެ.","",""],["","","","وهو الذي مد الأرض وجعل فيها رواسي وأنهارا ومن كل الثمرات جعل فيها زوجين اثنين يغشي الليل النهار إن في ذلك لآيات لقوم يتفكرون","އަދި އެކަލާނގެއީ، ބިން ފަތުރުއްވައި، އެ ބިމުގައި ހަރުލައި ހުންނަ ފަރުބަދަތަކާއި، ކޯރުތައް ލެއްވި ރަސްކަލާނގެއެވެ. އަދި އެއީ، ހުރިހާ ބާވަތެއްގެ މޭވާތައް، ޖޯޑުޖޯޑަށް (ދެވައްތަރުން ދެވައްތަރުން) ލެއްވި ރަސްކަލާނގެއެވެ. (އަދި) އެކަލާނގެ ރޭގަނޑުން ދުވާލު ނިވައިކުރައްވަތެވެ. ހަމަކަށަވަރުން، އެ (ހުރިހާ) ކަންތަކުގައި ފިކުރުކުރާ ބަޔަކަށް، ހެކިތަކެއް ވާކަން ކަށަވަރެވެ.","",""],["","","","وفي الأرض قطع متجاورات وجنات من أعناب وزرع ونخيل صنوان وغير صنوان يسقى بماء واحد ونفضل بعضها على بعض في الأكل إن في ذلك لآيات لقوم يعقلون","އަދި ކައިރިކައިރީގައިވާ ތަފާތު ބައިތައް، އެ ބިމުގައިވެއެވެ. އަދި މޭބިސްކަދުރާއި، ގޮވާމާއި، ކަދުރުރުއްތަކުގެ ބަގީޗާތައް ވެއެވެ. އެއްތަނޑަކަށް ހުންނަ ގަހާއި، އެއްތަނޑަކަށް ނުހުންނަ ގަހެވެ. އެ ހުރިހާ ތަކެއްޗަށް ދެވެނީ، އެއް ފެނެކެވެ. އަދި ތިމަންރަސްކަލާނގެ އޭގެ އެއްބާވަތް އަނެއް ބާވަތަށްވުރެ ކެއުމަށް މޮޅުކުރައްވަމެވެ. ހަމަކަށަވަރުން، އެ (ހުރިހާ) ކަންތަކުގައި، ވިސްނާ ބަޔަކަށް ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","وإن تعجب فعجب قولهم أإذا كنا ترابا أإنا لفي خلق جديد أولئك الذين كفروا بربهم وأولئك الأغلال في أعناقهم وأولئك أصحاب النار هم فيها خالدون","ކަލޭގެފާނު ކަމަކާމެދު އަޖާއިބު ވެވަޑައިގަންނަވާނަމަ، އެއުރެން އެބުނާ ބަހުގެ މައްޗަށް އަޖާއިބު ވެވަޑައިގަންނަވާށެވެ! ތިމަންމެން (މަރުވެ) ވެއްޔަށްވެއްޖެނަމަ، ހަމަކަށަވަރުން، ތިމަންމެން އަލުން އުފެދިދާނެހެއްޔެވެ؟ އެއުރެންނަކީ، އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ކާފިރު ވީ މީހުންނެވެ. އަދި އެއުރެންނަކީ އެއުރެންގެ ކަނދުރާތަކުގައި، ކަސްތަޅުއެޅިގެންވާ މީހުންނެވެ. އަދި އެއުރެންނަކީ، ނަރަކައިގެ އަހުލުވެރިންނެވެ. އެއުރެން އެތާނގައި ދެމިތިބޭހުށްޓެވެ.","",""],["","","","ويستعجلونك بالسيئة قبل الحسنة وقد خلت من قبلهم المثلات وإن ربك لذو مغفرة للناس على ظلمهم وإن ربك لشديد العقاب","އަދި ރަނގަޅު ކަންތަކުގެ ކުރިން، ނުބައިކަންތައް އަވަސްވުމަށް، ކަލޭގެފާނުގެ ކިބައިން އެއުރެން އެދެތެވެ. އަދި އެއުރެންގެ ކުރިން އިބްރަތް ލިބެނިވި ޢިގާބު އިސްވެގޮސްފައިވާކަން ކަށަވަރެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، މީސްތަކުން އަނިޔާވެރިވުމާއެކުވެސް، އެއުރެންނަށް ފާފަފުއްސެވުމުގެ ވެރިރަސްކަލާނގެއެވެ. އަދި ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ޢިގާބު ގަދަފަދަވެގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ويقول الذين كفروا لولا أنزل عليه آية من ربه إنما أنت منذر ولكل قوم هاد","އަދި ކާފިރު ވިމީހުން ބުނެތެވެ. އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ހެތްކެއް (އެބަހީ: މުއުޖިޒާއެއް) އެކަލޭގެފާނުގެ މައްޗަށް ބާވައިނުލެއްވީ ކީއްވެގެން ބާވައެވެ! ކަލޭގެފާނު ވާކަންކަށަވަރީ، އިންޒާރުކުރައްވާ ބޭކަލަކު ކަމުގައެވެ. އަދި ކޮންމެ ގައުމަކަށްމެ ތެދުމަގު ދައްކަވާ ރަސޫލަކު ވެއެވެ.","",""],["","","","الله يعلم ما تحمل كل أنثى وما تغيض الأرحام وما تزداد وكل شيء عنده بمقدار","ކޮންމެ އަންހެނަކުގެ މައިބަނޑުގައި ގަރުބަގަންނަ އެއްޗަކާއި، ރަޙިމުތައް އުނިކުރާ އެއްޗަކާއި، އިތުރުކުރާ އެއްޗެއް، ﷲ ދެނެވޮޑިގެންވެތެވެ. އަދި ކޮންމެ އެއްޗެއް އެކަލާނގެ ހަޒުރަތުގައި ވަނީ މިންވަރު ކުރައްވާފައެވެ.","",""],["","","","عالم الغيب والشهادة الكبير المتعال","(އެކަލާނގެއީ) ނުފެންނަ ކަންތަކާއި، ފެންނަ ކަންތައް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. ބޮޑުވެގެންވާ މަތިވެރިވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","سواء منكم من أسر القول ومن جهر به ومن هو مستخف بالليل وسارب بالنهار","ތިޔަބައިމީހުންކުރެ ބުނާ ބަސް ސިއްރުކުރާ މީހާއާއި، އެ ބަސް ފާޅުކުރާ މީހާއާއި، ރޭގަނޑު (އަނދިރީގައި) ފޮރުވިގެންވާ މީހާއާއި، ދުވާލު އެތަންމިތަނަށް ހިނގާމީހާ (އެކަލާނގެ ދެނެވޮޑިގަތުމުގައި) ހަމަހަމަވެގެންވެތެވެ.","",""],["","","","له معقبات من بين يديه ومن خلفه يحفظونه من أمر الله إن الله لا يغير ما بقوم حتى يغيروا ما بأنفسهم وإذا أراد الله بقوم سوءا فلا مرد له وما لهم من دونه من وال","އޭނާއަށް (އެބަހީ: އިންސާނާއަށް) އޭނާގެ ކުރިމަތީގައްޔާއި، އޭނާގެ ފަހަތުގައި، ބަދަލުވަމުންދާ ގޮތުގައި ތިއްބަވާ މަލާއިކަތުން ވެއެވެ. ﷲގެ އަމުރު ފުޅަށް، އެބޭކަލުން އޭނާ ރައްކާތެރިކޮށް ބަލަހައްޓަވަތެވެ. ހަމަކަށަވަރުން، ބަޔަކުމީހުންގެ ޙާލަތް އެބަޔަކު އަމިއްލަޔަށް ބަދަލުކޮށްފުމަށްދާނދެން، ﷲ، އެ ޙާލަތް ބަދަލެއް ނުކުރައްވާނެތެވެ. ހަމަކަށަވަރުން، ﷲ، ބަޔަކުމީހުންނަށް ނުބައިކަމަކަށް އިރާދަކުރައްވައިފި ހިނދަކު، އެކަން ދުރުކުރާނޭ އެއްވެސް ބާރެއް ނުވެތެވެ. އަދި އެކަލާނގެ ފިޔަވައި، އެއުރެންނަށް އެހީތެރިވާނޭ ފަރާތެއް ނުމެވޭމެއެވެ.","",""],["","","","هو الذي يريكم البرق خوفا وطمعا وينشئ السحاب الثقال","އެކަލާނގެއީ، ތިޔަބައިމީހުންނަށް ބިރުވެރިކަމާއި، އުއްމީދު ލިބެނިވިގޮތުގައި ވިދުވަރު ދައްކަވާ އަދި (ފެނުން) ބަރުވެފައިވާ ވިލާ އުފައްދަވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ويسبح الرعد بحمده والملائكة من خيفته ويرسل الصواعق فيصيب بها من يشاء وهم يجادلون في الله وهو شديد المحال","އަދި ގުގުރިވެސް އެކަލާނގެއަށް ހަމްދާއެކު ތަސްބީހަ ކިޔަތެވެ. އަދި މަލާއިކަތުން ވެސް އެކަލާނގެއަށް ބިރުވެތިކަމާއެކު ތަސްބީހަ ކިޔަތެވެ. އަދި ހޮނުއަޅުއްވައި، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް އެ ޖައްސަވަތެވެ. އަދި އެއުރެން ﷲއާމެދު ޖަދަލުކޮށް ހަދަތެވެ. އަދި އެކަލާނގެއީ، ހިއްޕެވުން ގަދަފަދަވެގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","له دعوة الحق والذين يدعون من دونه لا يستجيبون لهم بشيء إلا كباسط كفيه إلى الماء ليبلغ فاه وما هو ببالغه وما دعاء الكافرين إلا في ضلال","ހައްގު ވެގެންވާ ދުއާކުރުންވަނީ، ހަމައެކަނި އެކަލާނގެއަށެވެ. އަދި އެކަލާނގެ ފިޔަވައި، އެހެން ފަރާތްފަރާތަށް ދުއާކުރާ މީހުންނަކަށް އެފަރާތްތަކަކުން އެއްވެސް ކަމަކަށް އިޖާބައެއް ނުދޭނެތެވެ. ފެންގަނޑަކާދިމާޔަށް އެއިން ފެންފޮދެއް އަނގަޔަށް އެޅުމަށް (ދުރުގައި ހުރެގެން) ދެއަތްތިލަ ފަތުރާމީހެއްގެ މިސާލުގައި މެނުވީއެވެ. އޭނާޔަކަށް އެއިން ފެންފޮދެއް އަނގަޔަކަށް ނޭޅޭނެތެވެ. ކާފިރު ވީ މީހުންގެ ދުއާ، ގެއްލުމެއްގައި މެނުވީ ނުވެތެވެ.","",""],["","","","ولله يسجد من في السماوات والأرض طوعا وكرها وظلالهم بالغدو والآصال","އަދި އުޑުތަކާއި، ބިމުގައިވާހާ ބަޔަކާއި، އެއުރެންގެ ހިޔަނިތައްވެސް، ރުހުމުގައްޔާއި، ނުރުހުމުގައި، ހެނދުނާއި ހަވީރު، ﷲއަށް (ކިޔަމަންވެ) ސަޖިދަކުރެތެވެ.","",""],["","","","قل من رب السماوات والأرض قل الله قل أفاتخذتم من دونه أولياء لا يملكون لأنفسهم نفعا ولا ضرا قل هل يستوي الأعمى والبصير أم هل تستوي الظلمات والنور أم جعلوا لله شركاء خلقوا كخلقه فتشابه الخلق عليهم قل الله خالق كل شيء وهو الواحد القهار","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އުޑުތަކާއި، ބިމުގެ ވެރިރަސްކަލާނގެއަކީ ކާކުހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲއެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެ ތަކެތީގެ އަމިއްލަ ނަފްސުތަކަށް މަންފާއެއް، ނުވަތަ ގެއްލުމެއް ދިނުމުގެ ބާރު ލިބިގެންނުވާ ތަކެތި، އެކަލާނގެ ފިޔަވައި އެހީތެރިންކަމުގައި ތިޔަބައިމީހުން ހިފަނީހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ލޯކަނުމީހާއާއި، ލޮލަށް ފެންނަ މީހާއާ ހަމަހަމަވާނޭ ހެއްޔެވެ؟ ނުވަތަ އަނދިރިކަމާއި، އަލިކަމާ ހަމަހަމަވާނޭ ހެއްޔެވެ؟ ނުވަތަ އެއުރެން ﷲއަށް ބައިވެރިންތަކެއްލައި، އެ ބައިވެރިންތައް އެކަލާނގެ ހައްދަވާފައިވާކަހަލަ އެއްވެސް އެއްޗެއް ހަދައި، އެ (ދެފަރާތުގެ) މަޚްލޫގުން އެއުރެންނަށް އެއްގޮތްވެ، އޮޅިގެން އުޅެންޖެހުނުހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲއީ، ހުރިހާ އެއްޗެއް ހައްދަވާ ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެއީ، އެއްކައުވަންތަ، ބާރުވެރިވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","أنزل من السماء ماء فسالت أودية بقدرها فاحتمل السيل زبدا رابيا ومما يوقدون عليه في النار ابتغاء حلية أو متاع زبد مثله كذلك يضرب الله الحق والباطل فأما الزبد فيذهب جفاء وأما ما ينفع الناس فيمكث في الأرض كذلك يضرب الله الأمثال","އެކަލާނގެ އުޑުން ފެން ބާވައިލެއްވިއެވެ. ދެން ވާދީތަކުގައި ފެންބޮޑުވެ، އެއަށް ކަނޑައެޅިގެންވާ މިންވަރުގެމަތިން އޮހޮރިގެންދިޔައެވެ. ފަހެ، އެފެނުގެ މައްޗަށް އަރާ ފޮނުތައް، އެއާއެކު އުފުލައިގެން ގެންދިޔައެވެ. އަދި ގަހަނާއެއް ނުވަތަ ހިފައިގެންގުޅޭ އެއްޗެއް ހެދުމަށް އެއުރެން އަލިފާނަށްލައި ވިރުވާ މަޢުދަނުގެ މައްޗަށްވެސް އެފަދަ ދަގުއިއަރައެވެ. އެފަދައިން، ﷲ، ހައްގާއި ބާތިލުގެ މިސާލު ޖައްސަވަތެވެ. ފަހެ، މައްޗަށްއަރާ ފޮނު ދަންނާށެވެ! ބޭނުންނެތް ގޮތުގައި، އެ އުކައިލެވި، ގެއްލިދަނީއެވެ. އަދި މީސްތަކުންނަށް ފައިދާހުރި ކަންތައް ދަންނާށެވެ! ފަހެ، ބިމުގައި އެ، ހަރުލައި ހުންނާނެތެވެ. އެފަދައިން ﷲ މިސާލު ޖައްސަވަތެވެ.","",""],["","","","للذين استجابوا لربهم الحسنى والذين لم يستجيبوا له لو أن لهم ما في الأرض جميعا ومثله معه لافتدوا به أولئك لهم سوء الحساب ومأواهم جهنم وبئس المهاد","އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް އިޖާބަދިން މީހުންނަށް، ހުރީ، އެންމެ ހެޔޮ ދަރުމައެވެ. އަދި އެކަލާނގެއަށް އިޖާބަ ނުދިން މީހުންނަށް މުޅި ބިމުގައި ވާހައި ތަކެއްޗެއް އޭގެ ދެގުނަޔަށް ލިބުނުކަމުގައިވިޔަސް، އެ ހުރިހާ އެއްޗަކުން އެއުރެން ފިދުޔަ ދިނީހެވެ. އެއުރެންނަށްހުރީ، ނުބައިކަންހުރި ހިސާބު ބެއްލެވުމެކެވެ. އަދި އެއުރެން ތިބެނިވި ތަނަކީ، ނަރަކައެވެ. އަދި އެ ތަންމަތީގެހުރި ނުބައިކަމާއެވެ!","",""],["","","","أفمن يعلم أنما أنزل إليك من ربك الحق كمن هو أعمى إنما يتذكر أولو الألباب","ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ކަލޭގެފާނަށް ބާވައިލެއްވީ، ހައްގު ތެދުކަން ދަންނަ މީހާ، ލޯއަނދިރި މީހަކާ އެއްފަދަ މީހެއްކަމުގައި ވާނޭހެއްޔެވެ؟ ނަސޭހަތް ލިބިގަންނަކަން ކަށަވަރީ، ބުއްދީގެ އަހުލުވެރިންނެވެ.","",""],["","","","الذين يوفون بعهد الله ولا ينقضون الميثاق","އެއުރެންނަކީ، ﷲއަށް ވެފައިވާ ވައުދު ފުއްދާ، އަދި ކަށަވަރުވެގެންވާ އަހުދު އުވައިނުލާ މީހުންނެވެ.","",""],["","","","والذين يصلون ما أمر الله به أن يوصل ويخشون ربهم ويخافون سوء الحساب","އަދި އެއުރެންނަކީ، ގުޅިފައިވުމަށް ﷲ އަމުރުކުރައްވާފައިވާ ކަންތައްތައް ގުޅުވާ، އަދި އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ބިރުވެތިވާ، އަދި ހިސާބު ބެއްލެވުމުގެ ނުބައި ނަތީޖާއަކަށް ބިރުގަންނަ މީހުންނެވެ.","",""],["","","","والذين صبروا ابتغاء وجه ربهم وأقاموا الصلاة وأنفقوا مما رزقناهم سرا وعلانية ويدرءون بالحسنة السيئة أولئك لهم عقبى الدار","އަދި އެއުރެންނީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ ވަޖުހުފުޅު އަދައިގެން ކެތްތެރިވެ، ނަމާދު ގާއިމު ކޮށް، އަދި ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްވި ތަކެތިން، ސިއްރާއި ފާޅުގައި ހޭދަކޮށް، އަދި ހެޔޮކަންތަކުން ނުބައިކަންތައް ދުރުކުރާ މީހުންނެވެ. އެއުރެންނަށް އާޚިރަތުގައި އުފާވެރި ގޮވަތި ހުށްޓެވެ.","",""],["","","","جنات عدن يدخلونها ومن صلح من آبائهم وأزواجهم وذرياتهم والملائكة يدخلون عليهم من كل باب","(އެއީ) ޢަދްނު އޭ ކިއުނު ސުވަރުގެތަކެވެ. އެ ސުވަރުގެތަކަށް އެއުރެންނާއި، އެއުރެންގެ މައިންބަފައިންނާއި، އެއުރެންގެ އަނބިންނާއި، އެއުރެންގެ ދަރިންކުރެ ސާލިހުވި މީހުން ވަންނާނެތެވެ. އަދި އެތާނގެ ހުރިހާ ދޮރަކުން، މަލާއިކަތުން އެއުރެންގެ ގާތަށް ވެދެވަޑައިގަންނަވާނެތެވެ.","",""],["","","","سلام عليكم بما صبرتم فنعم عقبى الدار","(އެބޭކަލުން ވިދާޅުވާނެތެވެ.) ތިޔަބައިމީހުން ކެތްތެރިވިކަމަށްޓަކައި، ތިޔަބައިމީހުންގެ މައްޗަށް ސަލާމް ހުށްޓެވެ. ފަހެ، އާޚިރަތްގެ އުފާވެރި ގޮވަތީގެ މޮޅުކަމާއެވެ!","",""],["","","","والذين ينقضون عهد الله من بعد ميثاقه ويقطعون ما أمر الله به أن يوصل ويفسدون في الأرض أولئك لهم اللعنة ولهم سوء الدار","އަދި ﷲއަށް އަހުދު ކަށަވަރުކުރުމަށްފަހު، އެ އަހުދު އުވާލައި، އަދި ގުޅިފައިވުމަށް ﷲ އަމުރުކުރައްވާފައިވާ ގުޅުންތައް ކަނޑާލައި، އަދި ބިމުގައި ފަސާދަކުރާ މީހުންނާމެދު (ދަންނާށެވެ!) އެއުރެންނަށް ލައުނަތް ހުށްޓެވެ. އަދި އާޚިރަތް ދުވަހުން އެއުރެންނަށް ނުބައިވެގެންވާ ގޮވަތި ހުށްޓެވެ.","",""],["","","","الله يبسط الرزق لمن يشاء ويقدر وفرحوا بالحياة الدنيا وما الحياة الدنيا في الآخرة إلا متاع","ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ރިޒްގު ތަނަވަސްކޮށްދެއްވައި، އަދި (އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ރިޒްގު) ދަތިކުރައްވަތެވެ. އަދި ދުނިޔޭގެ ދިރިއުޅުމާމެދު އެއުރެން އުފާކުރޫއެވެ. އަދި ދުނިޔޭގެ ދިރިއުޅުމަކީ، އާޚިރަތްގެ ދިރިއުޅުމާ އަޅައިބަލާއިރު، ވަގުތީ އުފަލެއްކަމުގައި މެނުވީ ނުވެތެވެ.","",""],["","","","ويقول الذين كفروا لولا أنزل عليه آية من ربه قل إن الله يضل من يشاء ويهدي إليه من أناب","ކާފިރުވި މީހުން ބުނެތެވެ. އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ހެތްކެއް އެކަލޭގެފާނުގެ މައްޗަށް ބާވައިނުލެއްވީ، ކީއްވެގެން ބާވައެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ﷲ އިރާދަކުރައްވާ މީހަކު މަގުފުރައްދަވަތެވެ. އަދި އެކަލާނގެ ހަޒުރަތަށް އެނބުރި އަންނަ މީހަކަށް ތެދުމަގު ދައްކަވަތެވެ.","",""],["","","","الذين آمنوا وتطمئن قلوبهم بذكر الله ألا بذكر الله تطمئن القلوب","އެއުރެންނީ، އީމާންވި މީހުންނެވެ. އަދި ﷲ ހަނދުމަކުރުމުން، އެއުރެންގެ ހިތްތައް ހަމަޖެހޭ މީހުންނެވެ. ހިތްތައް ހަމަޖެހެނީ، ﷲ ހަނދުމަކުރުމުން ނޫންހެއްޔެވެ؟","",""],["","","","الذين آمنوا وعملوا الصالحات طوبى لهم وحسن مآب","އެއުރެންނީ، އީމާންވެ، ސާލިހު ޢަމަލުތައްކުޅަ މީހުންނެވެ. އެއުރެންނަށް އުފާވެރިކަމާއި، އަދި އެނބުރިދަނިވި ރިވެތިވެގެންވާ ތަނެއްވެއެވެ.","",""],["","","","كذلك أرسلناك في أمة قد خلت من قبلها أمم لتتلو عليهم الذي أوحينا إليك وهم يكفرون بالرحمن قل هو ربي لا إله إلا هو عليه توكلت وإليه متاب","އެފަދައިން ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު އުއްމަތެއްގެތެރެއަށް ފޮނުއްވީމެވެ. އެ އުއްމަތްގެ ކުރީގައި، އެތައް އުއްމަތް ތަކެއް ނިމިގޮސްފައިވެއެވެ. (އެއީ) ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް އިއްވެވި ވަހީއެއުރެންނަށް ކަލޭގެފާނު ކިޔައިދެއްވުމަށްޓަކައެވެ. (ނަމަވެސް) އެއުރެން ރަޙްމާންވަންތަ ރަސްކަލާނގެއަށް ކާފިރު ވެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއީ ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއެވެ. އެކަލާނގެ ފިޔަވައި، އެހެން އިލާހަކު ނުވެއެވެ. ތިމަންކަލޭގެފާނު ވަކީލުކުރައްވަނީ، އެކަލާނގެއަށެވެ. އަދި ތިމަންކަލޭގެފާނު އެނބުރި ދިއުންވަނީ އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","ولو أن قرآنا سيرت به الجبال أو قطعت به الأرض أو كلم به الموتى بل لله الأمر جميعا أفلم ييأس الذين آمنوا أن لو يشاء الله لهدى الناس جميعا ولا يزال الذين كفروا تصيبهم بما صنعوا قارعة أو تحل قريبا من دارهم حتى يأتي وعد الله إن الله لا يخلف الميعاد","ގުރްއާނަކުން ފަރުބަދަތައް ލުހެލެވި، ފުނޑުފުނޑުކޮށްލެވޭނެނަމަ، ނުވަތަ ބިންގަނޑު ކުދިކުދި ކޮށްލެވޭނެނަމަ، ނުވަތަ މަރުވެފައިވާ މީހުންނާ ވާހަކަ ދެއްކޭނެނަމަ (އެ ގުރްއާނަކީ މިއީއެވެ.) އަދި ކިއެއްތަ! ހުރިހާ އަމުރެއް ކުރެއްވުންވަނީ، ﷲއަށެވެ. ފަހެ، ﷲ އިރާދަކުރައްވާނަމަ، އެންމެހާ މީސްތަކުންނަށް ތެދުމަގު ދައްކަވައިފާނެކަން، އީމާން ވިމީހުންނަށް ނޭނގޭހެއްޔެވެ؟ ކާފިރު ވިމީހުންނަށް އެއުރެންކުރި ކަންތައްތަކުން، އާފާތުތައްޖެހި، ނުވަތަ އެ އާފާތުތައް، އެއުރެންގެ ގޮވަތިގެދޮރާ ކައިރިއަށް އައުން ފިލައިނުދެއެވެ. ﷲގެ ވައުދުފުޅު އަތުވެއްޖައުމަށް ދާނދެނެވެ. ހަމަކަށަވަރުން، ﷲ، ވައުދާ ޚިލާފު ވެވޮޑިއެއް ނުގަންނަވަތެވެ.","",""],["","","","ولقد استهزئ برسل من قبلك فأمليت للذين كفروا ثم أخذتهم فكيف كان عقاب","އަދި ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ކުރިންވެސް، ރަސޫލުންނަށް ފުރައްސާރަ ކުރިއެވެ. ފަހެ، ކާފިރުވި މީހުންނަށް ތިމަންރަސްކަލާނގެ މުހުލަތް ދެއްވީމެވެ. ދެން ތިމަންރަސްކަލާނގެ އުގޫބާތް ދެއްވައި، އެއުރެން ހިއްޕެވީމެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ އުގޫބާތް ދެއްވުންވީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","أفمن هو قائم على كل نفس بما كسبت وجعلوا لله شركاء قل سموهم أم تنبئونه بما لا يعلم في الأرض أم بظاهر من القول بل زين للذين كفروا مكرهم وصدوا عن السبيل ومن يضلل الله فما له من هاد","ފަހެ، ކޮންމެ ނަފްސަކާއި، އެ ނަފްސެއް ހޯދައިގަތް ޢަމަލުތަކުގެ މައްޗަށް ގާއިމުވެ ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެ (އެނޫން ފަރާތަކާ އެއްފަދަވާނޭ ހެއްޔެވެ؟) އަދި އެއުރެން، ﷲއަށް ޝަރީކުންތަކެއް ލޫއެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން އެ ތަކެއްޗަށް ނަންދީ ބަލާށެވެ! ނުވަތަ ބިމުގައި އެކަލާނގެ ދެނެވޮޑިގެންނުވާ ކަމެއްގެ ޚަބަރު، ތިޔަބައިމީހުން އެކަލާނގެއަށް ދެނީހެއްޔެވެ؟ ނުވަތަ ބޭރުފުށުން ދައްކާ ވާހަކައަކީ ހެއްޔެވެ؟ އަދި ކީއްހެއްޔެވެ؟ ކާފިރުވި މީހުންނަށް، އެއުރެންގެ މަކަރުވެރި ރޭވުންތައް ޒީނަތްތެރިކުރެއްވިއެވެ. އަދި އެއުރެން މަގުން އެއްކިބާކުރައްވާފައިވެއެވެ. ﷲ މަގުފުރައްދަވާ މީހަކަށް ތެދުމަގު ދައްކާނޭ އެކަކުވެސް ނުވެތެވެ.","",""],["","","","لهم عذاب في الحياة الدنيا ولعذاب الآخرة أشق وما لهم من الله من واق","އެއުރެންނަށް ދުނިޔޭގެ ހަޔާތް ގައިވެސް އަޒާބު ހުށްޓެވެ. އަދި ހަމަކަށަވަރުން، އާޚިރަތްގެ އަޒާބު މާގަދައެވެ. އަދި ﷲގެ އަޒާބުން ރައްކާތެރިކޮށްދޭނެ އެކަކުވެސް އެއުރެންނަކަށް ނުވެތެވެ.","",""],["","","","مثل الجنة التي وعد المتقون تجري من تحتها الأنهار أكلها دائم وظلها تلك عقبى الذين اتقوا وعقبى الكافرين النار","ތަގުވާވެރިންނަށް ވައުދުކުރައްވާފައިވާ ސުވަރުގޭގެ މިސާލު (ކިޔައިދެއްވަމެވެ.) އެތާނގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުރެތެވެ. އެތާނގެ މޭވާތައް އަބަދަށް ދެމިހުރެތެވެ. އަދި އެތާނގެ ހިޔާވެސް އެފަދައެވެ. އެއީ ތަގުވާވެރިވި މީހުންގެ ނިމުމެވެ. އަދި ކާފިރުވި މީހުންގެ ނިމުމަކީ ނަރަކައެވެ.","",""],["","","","والذين آتيناهم الكتاب يفرحون بما أنزل إليك ومن الأحزاب من ينكر بعضه قل إنما أمرت أن أعبد الله ولا أشرك به إليه أدعو وإليه مآب","ތިމަންރަސްކަލާނގެ ފޮތް ދެއްވި މީހުން، ކަލޭގެފާނަށް ބާވައިލެއްވި ތަކެއްޗާމެދު އުފާކުރެތެވެ. އަދި އޭގެ ބައެއް ތަކެއްޗާމެދު އިންކާރުކުރާ ބަޔަކު އަޙްޒާބުގެ ތެރެއިން (އެބަހީ: މުޝްރިކްނާއި، ފޮތުގެ އަހުލުވެރިންކުރެ އީމާން ނުވާ މީހުންގެ ތެރެއިން) ވެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނަށް އަމުރުކުރައްވާފައިވާކަން ކަށަވަރީ، ﷲއަށް އަޅުކަން ކުޅައުމަށެވެ. އަދި އެކަލާނގެއަށް ޝަރީކު ނުކުރުމަށެވެ. ތިމަންކަލޭގެފާނު ގޮވައިލައްވަނީ، އެކަލާނގެއަށް އަޅުކަންކުރުމަށެވެ. އަދި ތިމަންކަލޭގެފާނު އެނބުރިދިއުންވަނީ އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","وكذلك أنزلناه حكما عربيا ولئن اتبعت أهواءهم بعد ما جاءك من العلم ما لك من الله من ولي ولا واق","އެފަދައިން އަރަބި ބަހުންވާ ހުކުމެއްގެ ގޮތުގައި، ތިމަންރަސްކަލާނގެ އެ ގުރްއާން ބާވައިލެއްވީމެވެ. އަދި ކަލޭގެފާނާ ހަމައަށް އައި އިލްމަށްފަހު، އެއުރެންގެ އަމިއްލަ އެދުމަށް ކަލޭގެފާނު ތަބާ ވެވަޑައިގެންފިނަމަ، ﷲއާ ދެކޮޅަށް ނަސްރު ދޭނެ މީހަކުވެސް، އަދި އަޒާބުން ރައްކާތެރިކުރާނޭ މީހަކުވެސް ކަލޭގެފާނަކަށް ނުވެތެވެ.","",""],["","","","ولقد أرسلنا رسلا من قبلك وجعلنا لهم أزواجا وذرية وما كان لرسول أن يأتي بآية إلا بإذن الله لكل أجل كتاب","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ކުރިން ތިމަންރަސްކަލާނގެ ރަސޫލުން ފޮނުއްވީމެވެ. އަދި އެބޭކަލުންނަށް އަނބިންނާއި، ދަރިން ލެއްވީމެވެ. އަދި ﷲގެ އިޒުނަ ފުޅާ ލައިގެންމެނުވީ، އެއްވެސް މުއުޖިޒާއެއް ގެންނެވުމަކީ، އެއްވެސް ރަސޫލަކަށް އޮތްކަމެއް ނޫނެވެ. ކޮންމެ މުއްދަތަކަށްމެ ކަނޑައެޅި، ލިޔެވިގެންވާ ފޮތެއްވެއެވެ.","",""],["","","","يمحو الله ما يشاء ويثبت وعنده أم الكتاب","ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ ކޮންމެ ކަމެއް ފުހެލައްވަތެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވާ ކޮންމެކަމެއް ސާބިތުކުރައްވަތެވެ. އަދި އެކަލާނގެ ހަޒުރަތުގައި، މައިފޮތް (އެބަހީ: اللوح المحفوظ) ވެއެވެ.","",""],["","","","وإن ما نرينك بعض الذي نعدهم أو نتوفينك فإنما عليك البلاغ وعلينا الحساب","ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ވައުދުކުރައްވާ ބައެއް ކަންތައް ކަލޭގެފާނަށް ދައްކަވާނަމަ، ނުވަތަ (އޭގެކުރިން) ކަލޭގެފާނުގެ ފުރާނަ ހިއްޕަވާނަމަ، ފަހެ، ކަލޭގެފާނުގެ މައްޗަށް އޮތްކަން ކަށަވަރީ (މީސްތަކުންނަށް) އިއްވެވުމެވެ. އަދި ހިސާބު ބެއްލެވުންވަނީ، ތިމަންރަސްކަލާނގެއަށެވެ.","",""],["","","","أولم يروا أنا نأتي الأرض ننقصها من أطرافها والله يحكم لا معقب لحكمه وهو سريع الحساب","އަދި ތިމަންރަސްކަލާނގެ، ބިމާމެދު އިރާދަކުރައްވައި، އެ ބިމުގެ ކަންކޮޅުތަކުން އުނިކުރައްވާކަން، އެއުރެންނަށް ނޭނގޭހެއްޔެވެ؟ اللًّه، ހުކުމްކުރައްވަތެވެ. އެކަލާނގެ ހުކުމަށް ބަދަލެއްގެންނާނޭ އެއްވެސް ފަރާތެއް ނުވެތެވެ. އަދި އެކަލާނގެއީ، ހިސާބު ބެއްލެވުން އަވަސްވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وقد مكر الذين من قبلهم فلله المكر جميعا يعلم ما تكسب كل نفس وسيعلم الكفار لمن عقبى الدار","ހަމަކަށަވަރުން، އެއުރެންގެ ކުރީގައި އުޅުނު މީހުންވެސް، މަކަރުވެރި ރޭވުންތައް ރާވައި އުޅުނޫއެވެ. ފަހެ، ހުރިހާ ރޭވުމެއްވަނީ، ﷲއަށެވެ. ކޮންމެ ނަފްސެއް ހޯދައިގަންނަކަމެއް، އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަދި އާޚިރަތްގެ ނިއުމަތްގެ ގޮވަތި ވަނީ، ކޮންބަޔަކަށްކަން، ކާފިރު ތަކުންނަށް އެނގޭހުށްޓެވެ.","",""],["","","","ويقول الذين كفروا لست مرسلا قل كفى بالله شهيدا بيني وبينكم ومن عنده علم الكتاب","ކާފިރުވި މީހުން ބުނެތެވެ. ކަލޭގެފާނީ، ފޮނުއްވާފައިވާ ބޭކަލެއްނޫނެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނާއި، ތިޔަބައިމީހުންނާ ދެމެދުގައި ހެތްކެއްކަމަށް ﷲ ފުދެތެވެ. އަދި ފޮތުގެއިލްމު ލިބިގެންވާ މީހުންވެސްމެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم الر كتاب أنزلناه إليك لتخرج الناس من الظلمات إلى النور بإذن ربهم إلى صراط العزيز الحميد","ل ر (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.) (މިއީ) ފޮތެކެވެ. އެ ފޮތް ކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ ބާވައިލެއްވީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ އިޒުނަ ފުޅާއެކު، އަނދިރިކަމުގެ ތެރެއިން އަލިކަމުގެ ތެރެއަށް ކަލޭގެފާނު، މީސްތަކުން ނެރުއްވުމަށެވެ. ގަދަފަދަވަންތަ، ހަމްދު ލިބިވޮޑިގެންވާ ރަސްކަލާނގެ (ދެއްކެވި) މަގަށެވެ.","",""],["","","","الله الذي له ما في السماوات وما في الأرض وويل للكافرين من عذاب شديد","ﷲގެ މަގެވެ. އެކަލާނގެއީ، އުޑުތަކުގައި ވާހާ އެއްޗަކާއި، ބިމުގައި ވާހާ އެއްޗެއް މިލްކުވެގެންވާ ރަސްކަލާނގެއެވެ. އަދި ކާފިރުންނަށް ގަދަފަދަވެގެންވާ އަޒާބަކުން ހަލާކު ހުށްޓެވެ.","",""],["","","","الذين يستحبون الحياة الدنيا على الآخرة ويصدون عن سبيل الله ويبغونها عوجا أولئك في ضلال بعيد","އެއުރެންނީ، އާޚިރަތަށްވުރެ ބޮޑަށް ދުނިޔޭގެ ދިރިއުޅުމަށް ލޯބިކުރާ މީހުންނެވެ. އަދި ﷲގެ މަގުން (މީސްތަކުން) އެއްކިބާކޮށް، އެ މަގު ގުދުވުމަށް އެދޭ މީހުންނެވެ. އެއުރެންވަނީ، ދުރުވެގެންވާ މަގުފުރެދުމެއްގައެވެ.","",""],["","","","وما أرسلنا من رسول إلا بلسان قومه ليبين لهم فيضل الله من يشاء ويهدي من يشاء وهو العزيز الحكيم","ތިމަންރަސްކަލާނގެ އެއްވެސް ރަސޫލަކު އެބޭކަލެއްގެ ގައުމުގެބަހުން މެނުވީ ނުފޮނުއްވަމެވެ. (އެއީ) އެއުރެންނަށް ސާފުކޮށް ބަޔާންކޮށްދެއްވުމަށްޓަކައެވެ. ފަހެ، ﷲ އިރާދަކުރައްވާ އަޅަކު، މަގުފުރައްދަވަތެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވާ އަޅަކަށް ތެދުމަގު ދައްކަވަތެވެ. އެކަލާނގެއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ولقد أرسلنا موسى بآياتنا أن أخرج قومك من الظلمات إلى النور وذكرهم بأيام الله إن في ذلك لآيات لكل صبار شكور","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާއިގެން، މޫސާގެފާނު ފޮނުއްވީމެވެ. (އަދި އެންގެވީމެވެ.) ކަލޭގެފާނުގެ ގައުމުގެމީހުން އަނދިރިކަމުގެ ތެރެއިން، އަލިކަމުގެ ތެރެއަށް ނެރުއްވާށެވެ! އަދި އެއުރެންނަށް ﷲގެ ދުވަސްތައް ހަނދުމަކޮށްދެއްވާށެވެ! ހަމަކަށަވަރުން، ކެތްތެރިކަން ބޮޑު، ޝުކުރުވެރިވުން ގިނަ ކޮންމެ މީހަކަށް، އެކަންތަކުގައި ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","وإذ قال موسى لقومه اذكروا نعمة الله عليكم إذ أنجاكم من آل فرعون يسومونكم سوء العذاب ويذبحون أبناءكم ويستحيون نساءكم وفي ذلكم بلاء من ربكم عظيم","މޫސާގެފާނު އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް ވިދާޅުވިހިނދު (ހަނދުމަކުރާށެވެ!) ތިޔަބައިމީހުންނަށް ﷲ ދެއްވި ނިއުމަތްތައް، ތިޔަބައިމީހުން ހަނދާންކުރާށެވެ! ފިރްޢައުނުގެ މީހުންގެ ކިބައިން އެކަލާނގެ ތިޔަބައިމީހުން ސަލާމަތް ކުރެއްވި ހިނދެވެ. އެއުރެން ތިޔަބައިމީހުންނަށް ގަދަފަދަވެގެންވާ އަޒާބުގެ ރަހަ ދައްކަމުން ގެންދެތެވެ. އަދި އެއުރެން ތިޔަބައިމީހުންގެ ފިރިހެންދަރިން ކަތިލައި، އަދި ތިޔަބައިމީހުންގެ އަންހެންދަރިން ނުމަރައި ބައިތިއްބަތެވެ. އަދި އެކަންތަކުގައި ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައިސްފައިވާ ބޮޑު އިމްތިހާނެއް ވެއެވެ.","",""],["","","","وإذ تأذن ربكم لئن شكرتم لأزيدنكم ولئن كفرتم إن عذابي لشديد","އަދި ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ އެންގެވިހިނދު ހަނދުމަކުރާށެވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ޝުކުރު ކޮށްފިނަމަ، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް އިތުރުކޮށްދެއްވާހުށީމެވެ. އަދި ތިޔަބައިމީހުން (ޝުކުރު ނުކޮށް) ކާފިރު ވެއްޖެނަމަ (ދަންނާށެވެ!) ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އަޒާބު ގަދަފަދަވެގެންވާކަން ކަށަވަރެވެ.","",""],["","","","وقال موسى إن تكفروا أنتم ومن في الأرض جميعا فإن الله لغني حميد","އަދި މޫސާގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންނާއި، ބިމުގައި ވާހާ އެންމެން (ޝުކުރު ނުކޮށް) ކާފިރު ވިޔަސް، ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ފުދިވޮޑިގެންވާ، ހަމްދު ލިބިވޮޑިގެންވާ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","ألم يأتكم نبأ الذين من قبلكم قوم نوح وعاد وثمود والذين من بعدهم لا يعلمهم إلا الله جاءتهم رسلهم بالبينات فردوا أيديهم في أفواههم وقالوا إنا كفرنا بما أرسلتم به وإنا لفي شك مما تدعوننا إليه مريب","ތިޔަބައިމީހުންގެ ކުރިން އުޅުނު މީހުންގެ ޚަބަރު ތިޔަބައިމީހުންނާ ހަމަޔަކަށް ނާދޭހެއްޔެވެ؟ (އެއީ) ނޫޙުގެފާނުގެ ގައުމުގެމީހުންނާއި، ޢާދު ބާގައިމީހުންނާއި، ޘަމޫދު ބާގައިމީހުންނާއި، އެއުރެންގެ ފަހުން އުޅުނު މީހުންނެވެ. ﷲއަށް މެނުވީ، އެއުރެންނެއް ނޭނގެތެވެ. އެއުރެންގެ ގާތަށް އެއުރެންގެ ރަސޫލުން ބަޔާންވެގެންވާ ހެކިތަކާއިގެން ވަޑައިގަތެވެ. ފަހެ، އެއުރެންގެ އަނގަތަކުގައި، އެއުރެންގެ އަތްތައް އެޅޫއެވެ. އަދި އެއުރެން ބުނެފޫއެވެ. ހަމަކަށަވަރުން، ތިޔަބޭކަލުން އެކަމަކާއިގެން ފޮނުއްވެވި ކަންތަކަށް ތިމަންމެން ކާފިރު ވެއްޖައީމެވެ. އަދި ހަމަކަށަވަރުން، ތިޔަބޭކަލުން އެކަމަކަށް ތިމަންމެންނަށް ގޮވައިލައްވާ ކަމަކާމެދު، ހަމަކަށަވަރުން، ތިމަންމެންވަނީ ވަސްވާސްތެރިކަމުން ފުރިގެންވާ ޝައްކެއް ގައެވެ.","",""],["","","","قالت رسلهم أفي الله شك فاطر السماوات والأرض يدعوكم ليغفر لكم من ذنوبكم ويؤخركم إلى أجل مسمى قالوا إن أنتم إلا بشر مثلنا تريدون أن تصدونا عما كان يعبد آباؤنا فأتونا بسلطان مبين","އެއުރެންގެ ރަސޫލުން ވިދާޅުވޫއެވެ. އިސްވެދިޔަ މިސާލަކާނުލައި އުޑުތަކާއި ބިން އުފެއްދެވި ﷲއާމެދު، ޝައްކެއް ވޭހެއްޔެވެ؟ އެކަލާނގެ ތިޔަބައިމީހުންނަށް ގޮވައިލައްވަނީ، ތިޔަބައިމީހުންނަށް ތިޔަބައިމީހުންގެ ފާފަތައް ފުއްސަވައިދެއްވުމަށާއި، ކަނޑައެޅިގެންވާ މުއްދަތަކަށް ތިޔަބައިމީހުން ފަސްކުރެއްވުމަށްޓަކައެވެ. އެއުރެން ދެންނެވޫއެވެ. ތިމަންމެންކަހަލަ އިންސާނުން ކަމުގައި މެނުވީ ތިޔަބޭކަލުން ނުވަމުއެވެ. ތިޔަބޭކަލުން އެދިވަޑައިގަންނަވަނީ، ތިމަންމެންގެ ކާބަފައިން އަޅުކަންކޮށް އުޅުނު ތަކެތިން ތިމަންމެން ދުރުކުރެއްވުމަށެވެ. ފަހެ، ބަޔާންވެގެންވާ ހުއްޖަތެއް ތިމަންމެންނަށް ތިޔަބޭކަލުން ގެނެސްދެއްވަ ބައްލަވާށެވެ!","",""],["","","","قالت لهم رسلهم إن نحن إلا بشر مثلكم ولكن الله يمن على من يشاء من عباده وما كان لنا أن نأتيكم بسلطان إلا بإذن الله وعلى الله فليتوكل المؤمنون","އެއުރެންގެ ރަސޫލުން އެއުރެންނަށް ވިދާޅުވޫއެވެ. ތިޔަބައިމީހުން ކަހަލަ އިންސާނުން ކަމުގައި މެނުވީ، ތިމަންމެން ނުވަމުއެވެ. އެހެނެއްކަމަކު، ﷲ، އެކަލާނގެ އަޅުންކުރެ އިރާދަކުރެއްވި ބަޔަކަށް ނިއުމަތް ދެއްވަތެވެ. އަދި ﷲގެ އިޒުނަ ފުޅާލައިގެން މެނުވީ، ތިޔަބައިމީހުންނަށް ހުއްޖަތެއް ގެނެސްދިނުމަކީ، ތިމަންމެންނަށް އޮތްކަމެއް ނޫނެވެ. އަދި މުއުމިނު ތަކުން ހަމައެކަނި ﷲއަށް ވަކީލުކުރާހުށިކަމެވެ!","",""],["","","","وما لنا ألا نتوكل على الله وقد هدانا سبلنا ولنصبرن على ما آذيتمونا وعلى الله فليتوكل المتوكلون","އަދި ހަމަކަށަވަރުން، އެކަލާނގެ ތިމަންމެންނަށް ތިމަންމެންގެ މަގުތައް ދައްކަވާފައިވާއިރު، ﷲއަށް ތިމަންމެން ވަކީލު ނުކުރަންވީ ކީއްވެގެން ހެއްޔެވެ؟ އަދި ތިޔަބައިމީހުން ތިމަންމެންނަށް ދިން އުނދަގޫތަކަށް ހަމަކަށަވަރުން، ތިމަންމެން ކެތްކުރާހުށީމުއެވެ. އަދި ވަކީލުކުރާމީހުން، ހަމައެކަނި ﷲއަށް ވަކީލުކުރާހުށިކަމެވެ!","",""],["","","","وقال الذين كفروا لرسلهم لنخرجنكم من أرضنا أو لتعودن في ملتنا فأوحى إليهم ربهم لنهلكن الظالمين","ކާފިރުވި މީހުން، އެއުރެންގެ ރަސޫލުންނަށް ދެންނެވޫއެވެ. ހަމަކަށަވަރުން، ތިމަންމެންގެ ބިމުން ތިޔަބޭކަލުން ނެރެލާހުށީމުއެވެ. ނޫންނަމަ ތިޔަބޭކަލުން ތިމަންމެންގެ ދީނަށް އެނބުރިވަޑައިގަންނަވާހުށިކަމެވެ! ފަހެ، އެބޭކަލުންގެ ވެރިރަސްކަލާނގެ، އެބޭކަލުންނަށް ވަހީކުރެއްވިއެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އަނިޔާވެރިން ހަލާކުކުރައްވާހުށީމެވެ.","",""],["","","","ولنسكننكم الأرض من بعدهم ذلك لمن خاف مقامي وخاف وعيد","އަދި ހަމަކަށަވަރުން، އެއުރެންގެ ފަހުގައި، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން، ބިމުގައި ވަޒަންވެރި ކުރައްވާ ހުށީމެވެ. އެކަންއޮތީ، ތިމަންރަސްކަލާނގެ (މަތިވެރި) މަގާމަށް ބިރުވެތިވެ، ތިމަންރަސްކަލާނގެ ވަޢީދަށް ބިރުވެތިވި މީހުންނަށެވެ.","",""],["","","","واستفتحوا وخاب كل جبار عنيد","އަދި އެބޭކަލުން ނަސްރަށް އެދި ދެންނެވޫއެވެ. އަދި ހަރުކަށި، ކޮންމެ ޖައްބާރަކު ގެއްލި ހަލާކުވިއެވެ.","",""],["","","","من ورائه جهنم ويسقى من ماء صديد","އޭނާގެ ކުރިމަތީގައިވަނީ، ނަރަކައެވެ. އަދި އޭނާއަށް ބޯންދެއްވާނީ، ފާ ދިޔަފަދަ ފެނަކުންނެވެ.","",""],["","","","يتجرعه ولا يكاد يسيغه ويأتيه الموت من كل مكان وما هو بميت ومن ورائه عذاب غليظ","އޭނާ އެ ދިރުވައިލާނެތެވެ. އޭނާއަށް އެ ދިރުވައިލެވޭނީ، ވަރަށް އުނދަގުލުންނެވެ. އަދި ހުރިހާ ފަރާތަކުން އޭނާގެ ގާތަށް މަރު އަންނާނެތެވެ. (އެކަމަކު) އޭނާ މަރެއް ނުވާނެތެވެ. އަދި އޭނާގެ ކުރިމަތީގައިވަނީ، ގަދަފަދަވެގެންވާ އަޒާބެވެ.","",""],["","","","مثل الذين كفروا بربهم أعمالهم كرماد اشتدت به الريح في يوم عاصف لا يقدرون مما كسبوا على شيء ذلك هو الضلال البعيد","އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ކާފިރުވި މީހުންގެ ޢަމަލުތަކުގެ މިސާލު، އަޅިތަކެއް ފަދައެވެ. ވިއްސާރަގަދަ ދުވަހެއްގައި، އެއަށް ގަދަ ވައިޖެހި، އެ އަޅިތައް ބުރުއްސައިލިއެވެ. އެއުރެން ހޯދައިގަތް އެއްވެސްކަމެއްގެ މައްޗަށް، އެއުރެންގެ އެއްވެސް ބާރެއް ނެތެވެ. ދުރުވެގެންވާ މަގުފުރެދުމަކީ ހަމައެއީއެވެ.","",""],["","","","ألم تر أن الله خلق السماوات والأرض بالحق إن يشأ يذهبكم ويأت بخلق جديد","ހަމަކަށަވަރުން، ﷲ، ހައްގު ގޮތުގައި އުޑުތަކާއި ބިން ހައްދަވާފައިވާކަން ތިބާއަކަށް ނޭނގޭ ހެއްޔެވެ؟ އެކަލާނގެ އިރާދަކުރައްވާނަމަ، ތިޔަބައިމީހުން ނެތިކޮށްލައްވައި، އާ މަޚްލޫގުންތަކެއް ގެންނަވައިފާނެތެވެ.","",""],["","","","وما ذلك على الله بعزيز","އަދި އެކަންތައް ﷲއަށް އުނދަގޫކަމަކަށް ނުވެތެވެ.","",""],["","","","وبرزوا لله جميعا فقال الضعفاء للذين استكبروا إنا كنا لكم تبعا فهل أنتم مغنون عنا من عذاب الله من شيء قالوا لو هدانا الله لهديناكم سواء علينا أجزعنا أم صبرنا ما لنا من محيص","އެ އެންމެން (ކަށްވަޅުތަކުން) ނުކުމެ، ﷲގެ ހަޒުރަތަށް އަންނާނެތެވެ. އަދި (އޭގެތެރެއިން) ނިކަމެތިން ބޮޑާވެގަތް މީހުންނަށް ބުނާނެތެވެ. ހަމަކަށަވަރުން، ތިމަންމެން މިތިބީ، ތިޔަބައިމީހުންނަށް ތަބާ ވެގެންނެވެ. ފަހެ، ތިޔަބައިމީހުންނަށް ﷲގެ އަޒާބުން ކުޑަމިންވަރެއްނަމަވެސް ތިމަންމެންގެ ކިބައިން ދުރުކޮށްދެވިދާނެ ހެއްޔެވެ؟ އެއުރެން ބުނާނެތެވެ. ﷲ ތިމަންމެންނަށް ތެދުމަގު ދެއްކެވިނަމަ، ތިޔަބައިމީހުންނަށް ތިމަންމެން ތެދުމަގު ދެއްކީމުހެވެ. ތިމަންމެން ކެތްނުކުރިޔަސް، ނުވަތަ ކެތްކުރިޔަސް، ތިމަންމެންގެ މައްޗަށް ހަމަހަމަވެގެންވެއެވެ. ފިލަންދާނެ ތަނެއް ތިމަންމެންނަކަށް ނުވެއެވެ.","",""],["","","","وقال الشيطان لما قضي الأمر إن الله وعدكم وعد الحق ووعدتكم فأخلفتكم وما كان لي عليكم من سلطان إلا أن دعوتكم فاستجبتم لي فلا تلوموني ولوموا أنفسكم ما أنا بمصرخكم وما أنتم بمصرخي إني كفرت بما أشركتمون من قبل إن الظالمين لهم عذاب أليم","އަދި ކަންތައް ނިޔާކުރައްވައި ނިމޭހިނދު، ޝައިތާނާ ބުނާނެތެވެ. ހަމަކަށަވަރުން، ﷲ، ތިޔަބައިމީހުންނަށް ވައުދުކުރައްވާފައިވަނީ، ހައްގު ތެދު ވައުދެވެ. އަދި ތިމަންވެސް ތިޔަބައިމީހުންނަށް ވައުދުކުރީމެވެ. ފަހެ، ތިޔަބައިމީހުންނަށް ތިމަންކުޅަ ވައުދާ ޚިލާފު ވީމެވެ. އަދި ތިޔަބައިމީހުންނަށް ތިމަން ގޮވައިލުން ފިޔަވައި، ތިޔަބައިމީހުންގެ މައްޗަށް އެއްވެސް ބާރެއް ތިމަންނާއަކަށް ލިބިގެނެއް ނުވެއެވެ. ފަހެ، ތިޔަބައިމީހުން ތިމަންނާގެ ގޮވައިލުމަށް އިޖާބަދިނީއެވެ. ފަހެ، ތިޔަބައިމީހުން ތިމަން ކުށްވެރިކޮށް ވާހަކަ ނުދައްކާށެވެ! އަދި ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތައް ކުށްވެރިކޮށް ވާހަކަ ދައްކާށެވެ! ތިޔަބައިމީހުންގެ އެހީތެރިޔަކަށް ތިމަން ނުވަމެވެ. އަދި ތިޔަބައިމީހުންވެސް ތިމަންގެ އެހީތެރިންނަކަށް ނުވަމުއެވެ. ހަމަކަށަވަރުން، މީގެކުރިން ތިޔަބައިމީހުން ތިމަން ބައިވެރިކުރި ކަންތަކަށް ތިމަން ކާފިރު ވީމެވެ. ހަމަކަށަވަރުން، އަނިޔާވެރިންނަށް ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["","","","وأدخل الذين آمنوا وعملوا الصالحات جنات تجري من تحتها الأنهار خالدين فيها بإذن ربهم تحيتهم فيها سلام","އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަމީހުން، އެތާނގެ ދަށުން ފެން ކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކަށް ވައްދަވާހުށްޓެވެ. އެއުރެންގެ ވެރިރަސްކަލާނގެ އިޒުނަ ފުޅާއެކު، އެތާނގައި އެއުރެން ދެމިތިބެނިވި ގޮތުގައެވެ. އެތާނގައި، އެއުރެންގެ ތަޙިއްޔަތަކީ، ސަލާމެވެ.","",""],["","","","ألم تر كيف ضرب الله مثلا كلمة طيبة كشجرة طيبة أصلها ثابت وفرعها في السماء","ﷲ، ރަނގަޅު ބަހެއްގެ މިސާލު ޖެއްސެވީ ކޮންފަދައަކުންކަން ކަލޭގެފާނު ދެކެވަޑައި ނުގަންނަވަމުތޯއެވެ؟ އެއީ، އެ ގަހެއްގެ މޫތައް (ބިމުގައި) ހަރުލާފައި ހުންނަ، އަދި އެ ގަހެއްގެ ގޮފިތައް (ބިޔަކޮށްހެދި) މައްޗަށް އުފުލިފައިވާ ގަހެއްގެ މިސާލެވެ.","",""],["","","","تؤتي أكلها كل حين بإذن ربها ويضرب الله الأمثال للناس لعلهم يتذكرون","އެ ގަހުގެ ވެރިރަސްކަލާނގެ އިޒުނަ ފުޅާއެކު، ހުރިހާ ހިނދެއްގައި އެ ގަހުގެ މޭވާ ލިބިދެއެވެ. ﷲ، މީސްތަކުންނަށް މިސާލު ޖައްސަވަނީ، އެއުރެން ހަނދުމަކުރުމަށްޓަކައެވެ.","",""],["","","","ومثل كلمة خبيثة كشجرة خبيثة اجتثت من فوق الأرض ما لها من قرار","އަދި ނުބައި ބަހެއްގެ މިސާލަކީ، ބިންމަތިން އުފުރާލި (އަދި) އެ ގަހަކަށް އެއްވެސް ސާބިތުކަމެއްނުވާ، ނުބައި ގަހެއްގެ މިސާލެވެ.","",""],["","","","يثبت الله الذين آمنوا بالقول الثابت في الحياة الدنيا وفي الآخرة ويضل الله الظالمين ويفعل الله ما يشاء","ދުނިޔޭގެ ހަޔާތް ގައްޔާއި، އާޚިރަތުގައި ސާބިތުވެގެންވާ (ހައްގު) ބަހުން އީމާންވި މީހުންނަށް، ﷲ ސާބިތުކަން ދެއްވަތެވެ. އަދި ﷲ، އަނިޔާވެރިން މަގުފުރައްދަވަތެވެ. އަދި ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ ކަމެއް ކުރައްވަތެވެ.","",""],["","","","ألم تر إلى الذين بدلوا نعمت الله كفرا وأحلوا قومهم دار البوار","ﷲގެ ނިއުމަތް، ކާފިރުކަމަށް ބަދަލުކޮށް، އެއުރެންގެ ގައުމު ހަލާކުގެ ގޮވައްޗަށްލީ މީހުން ކަލޭގެފާނު ދެކެވަޑައި ނުގަންނަވަމުތޯއެވެ؟","",""],["","","","جهنم يصلونها وبئس القرار","(އެއީ) ނަރަކައެވެ. އެއުރެން އެތަނަށްވަދެ އަނދާނެތެވެ. އަދި އެއީ، ތިބުމަށް ހާދަހާ ނުބައި ތަނެކެވެ!","",""],["","","","وجعلوا لله أندادا ليضلوا عن سبيله قل تمتعوا فإن مصيركم إلى النار","އަދި އެއުރެން ﷲއަށް ޝަރީކުން ލޫއެވެ. (އެއީ) އެއުރެން އެކަލާނގެ މަގުން މީސްތަކުން ފުރެއްދުމަށްޓަކައެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން (ދުނިޔެމަތީގައި) އަރާމުކޮށްލަން ތިބޭށެވެ! ފަހެ، ހަމަކަށަވަރުން، ތިޔަބައިމީހުން އެނބުރިދިއުންވަނީ ނަރަކައަށެވެ.","",""],["","","","قل لعبادي الذين آمنوا يقيموا الصلاة وينفقوا مما رزقناهم سرا وعلانية من قبل أن يأتي يوم لا بيع فيه ولا خلال","އީމާންވި، ތިމަންރަސްކަލާނގެ އަޅުންނަށް ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއުރެން ނަމާދު ގާއިމުކުރާހުށިކަމެވެ! އަދި ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްވި ތަކެތިން ސިއްރާއި ފާޅުގައި އެއުރެން ހޭދަކުރާހުށިކަމެވެ! އެ ދުވަހެއްގައި ވިޔަފާރިއެއް ނުވަތަ ރައްޓެހިކަމެއް ނޯންނާނޭ ދުވަހެއް އައުމުގެ ކުރިންނެވެ.","",""],["","","","الله الذي خلق السماوات والأرض وأنزل من السماء ماء فأخرج به من الثمرات رزقا لكم وسخر لكم الفلك لتجري في البحر بأمره وسخر لكم الأنهار","ﷲއީ، އުޑުތަކާއި ބިން ހެއްދެވި ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެ އުޑުން ވާރޭ ވެއްސެވިއެވެ. ފަހެ، އެ ފެނުގެ ސަބަބުން ތިޔަބައިމީހުންނަށް ރިޒްގެއް ކަމުގައި މޭވާތައް ނެރުއްވިއެވެ. އަދި އެކަލާނގެ އިޒުނަ ފުޅާއެކު، އެ ތަކެތި ކަނޑުގައި ދަތުރުކުރުމަށް ތިޔަބައިމީހުންނަށްޓަކައި ނާފަހަރު ޚިދުމަތް ތެރި ކުރެއްވިއެވެ. އަދި އެކަލާނގެ ތިޔަބައިމީހުންނަށްޓަކައި، ކޯރުތައް ޚިދުމަތް ތެރިކުރެއްވިއެވެ.","",""],["","","","وسخر لكم الشمس والقمر دائبين وسخر لكم الليل والنهار","އަދި އެކަލާނގެ ތިޔަބައިމީހުންނަށްޓަކައި، އިރާއި ހަނދު ޚިދުމަތް ތެރި ކުރެއްވިއެވެ. ކެނޑިނޭޅި ހިނގާގޮތުގައެވެ. އަދި އެކަލާނގެ ތިޔަބައިމީހުންނަށްޓަކައި، ރޭދުވާ ޚިދުމަތް ތެރި ކުރެއްވިއެވެ.","",""],["","","","وآتاكم من كل ما سألتموه وإن تعدوا نعمت الله لا تحصوها إن الإنسان لظلوم كفار","އަދި އެކަލާނގެ ހަޒުރަތަށް ތިޔަބައިމީހުން ދެންނެވި ކޮންމެ އެއްޗެއް އެކަލާނގެ ތިޔަބައިމީހުންނަށް ދެއްވިއެވެ. ﷲގެ ނިއުމަތްތައް ތިޔަބައިމީހުން ގުނާނަމަ، ތިޔަބައިމީހުންނަކަށް އެ ނިއުމަތްތައް އަދަދެއް ނުކުރެވޭހުށްޓެވެ. ހަމަކަށަވަރުން، އިންސާނާއަކީ، އަނިޔާވެރިވުން ބޮޑު، ޝުކުރުކުރުން ނެތްމީހެކެވެ.","",""],["","","","وإذ قال إبراهيم رب اجعل هذا البلد آمنا واجنبني وبني أن نعبد الأصنام","އިބްރާހީމްގެފާނު ވިދާޅުވި ހިނދު، ހަނދުމަކުރާށެވެ! އަޅުގެ ވެރިރަސްކަލާކޮ! މި ރަށަކީ، އަމާން ވެގެންވާ ރަށެއްކަމުގައި ލައްވާނދޭވެ! އަދި އަޅާއާއި، އަޅުގެ ދަރިން ބުދަށް އަޅުކަންކުރުމުން ދުރުކުރައްވާނދޭވެ!","",""],["","","","رب إنهن أضللن كثيرا من الناس فمن تبعني فإنه مني ومن عصاني فإنك غفور رحيم","އަޅުގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، އެ ބުދުތައް މީސްތަކުންކުރެ ގިނަބަޔަކު މަގުފުރައްދައިފިއެވެ. ފަހެ، މި އަޅާޔަށް ތަބާ ވެއްޖެ މީހަކީ، ހަމަކަށަވަރުން، އަޅުގެ (ދީންގެ) މީހެކެވެ. އަދި އަޅާޔަށް އުރެދިއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ربنا إني أسكنت من ذريتي بواد غير ذي زرع عند بيتك المحرم ربنا ليقيموا الصلاة فاجعل أفئدة من الناس تهوي إليهم وارزقهم من الثمرات لعلهم يشكرون","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، އަޅުގެ ދަރިންކުރެ ބަޔަކު، ގަހެއް ރުކެއް ނެތް ވާދީއެއްގައި، ހުރުމަތް ތެރި ކުރައްވާފައިވާ އިބަރަސްކަލާނގެ ގެފުޅު އަރިހުގައި، ވަޒަންވެރިކޮށްފީމެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! އެއުރެން ނަމާދު ގާއިމު ކޮށް އުޅުމަށްޓަކައެވެ. ފަހެ، މީސްތަކުންކުރެ ބަޔެއްގެ ހިތްތައް އެއުރެންގެ ފަރާތަށް ލަންބަވާނދޭވެ! އަދި މޭވާތަކުން އެއުރެންނަށް ރިޒްގު ދެއްވާނދޭވެ! (އެއީ) އެއުރެން ޝުކުރުވެރި ވުމަށްޓަކައެވެ.","",""],["","","","ربنا إنك تعلم ما نخفي وما نعلن وما يخفى على الله من شيء في الأرض ولا في السماء","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، އަޅަމެން ވަންހަނާކުރާ ކަންތަކާއި، އަޅަމެން ފާޅުކުރާ ކަންތައް، އިބަރަސްކަލާނގެ ދެނެވޮޑިގެންވަމުއެވެ. އަދި ބިމުގައްޔާއި، އުޑުގައިވާ އެއްވެސް އެއްޗެއް، ﷲއަށް ވަންހަނާވެގެނެއް ނުވެއެވެ.","",""],["","","","الحمد لله الذي وهب لي على الكبر إسماعيل وإسحاق إن ربي لسميع الدعاء","ހަމްދު ހުރީ، ﷲއަށެވެ. އެކަލާނގެއީ، އަޅު، މުސްކުޅިވެފައިވަނިކޮށް، އަޅާއަށް އިސްމާޢީލާއި، އިސްޙާގު ދެއްވި ރަސްކަލާނގެއެވެ. ހަމަކަށަވަރުން، އަޅުގެ ވެރިރަސްކަލާނގެއީ، ދުއާ އައްސަވާވޮޑިގެންވާ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","رب اجعلني مقيم الصلاة ومن ذريتي ربنا وتقبل دعاء","އަޅުގެ ވެރިރަސްކަލާކޮ! އަޅާއީ، ނަމާދު ގާއިމު ކޮށްއުޅޭ މީހެއްކަމުގައި ލައްވާނދޭވެ! އަދި އަޅާގެ ދަރިންކުރެންވެސްމެއެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަދި އަޅުގެ ދުއާ ގަބޫލުކުރައްވާނދޭވެ!","",""],["","","","ربنا اغفر لي ولوالدي وللمؤمنين يوم يقوم الحساب","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ހިސާބު ގާއިމުވާ ދުވަހު، އަޅާއަށާއި، އަޅުގެ މައިންބަފައިންނަށާއި، މުއުމިނު ތަކުންނަށް ފާފަފުއްސަވާނދޭވެ!","",""],["","","","ولا تحسبن الله غافلا عما يعمل الظالمون إنما يؤخرهم ليوم تشخص فيه الأبصار","އަނިޔާވެރިން ކުރާ ކަންތަކާމެދު، ﷲ، ޣާފިލުވެ ވޮޑިގެންވާކަމަށް ކަލޭގެފާނު ހީފުޅުނުކުރައްވާ ހުށިކަމެވެ! އެކަލާނގެ އެއުރެން ފަސްކުރައްވާކަން ކަށަވަރީ (ކަންތައް ބޮޑުވެ) ލޯތައް ހުޅުވޭ ދުވަހަކަށެވެ.","",""],["","","","مهطعين مقنعي رءوسهم لا يرتد إليهم طرفهم وأفئدتهم هواء","އެއުރެން އިސްއުފުލައި އަވަސްއަވަހަށް ހިނގާފައި ދާނެތެވެ. އެއުރެންގެ ލޮލުގެ އެސްފިޔަވެސް ޖަހައިނުލެވޭހުށްޓެވެ. އަދި އެއުރެންގެ ހިތްތައް ވާނީ، އެކައްޗެއްވެސް ނެތި ހުސްވެފައެވެ.","",""],["","","","وأنذر الناس يوم يأتيهم العذاب فيقول الذين ظلموا ربنا أخرنا إلى أجل قريب نجب دعوتك ونتبع الرسل أولم تكونوا أقسمتم من قبل ما لكم من زوال","އެއުރެންނަށް އަޒާބު އަންނަ ދުވަހާމެދު، ކަލޭގެފާނު މީސްތަކުންނަށް އިންޒާރުކުރައްވާށެވެ! ފަހެ، އަނިޔާވެރިވި މީހުން ބުނާނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ކައިރި މުއްދަތަކަށް އަޅަމެން ފަސްކުރައްވާނދޭވެ! އޭރުން އިބަރަސްކަލާނގެ ގޮވައިލެއްވުމަށް އަޅަމެން އިޖާބަދޭ ހުށީމުއެވެ. އަދި ރަސޫލުންނަށް ތަބާވާ ހުށީމުއެވެ. (ޖަވާބުގައި ބުނެވޭނެތެވެ.) ތިޔަބައިމީހުންނަށް (ދުނިޔެއިން) ނެތިދިއުމެއް ނާންނާނެކަމަށް މީގެކުރިން ތިޔަބައިމީހުން ހުވާކޮށް ނޫޅެމުހެއްޔެވެ؟","",""],["","","","وسكنتم في مساكن الذين ظلموا أنفسهم وتبين لكم كيف فعلنا بهم وضربنا لكم الأمثال","އަދި އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް އަނިޔާވެރިވި މީހުން އުޅުނު ތަންތާނގައި ތިޔަބައިމީހުން އުޅުނީމުއެވެ. އަދި އެއުރެންނާމެދު ތިމަންރަސްކަލާނގެ ކަންތައްކުރެއްވިގޮތް ތިޔަބައިމީހުންނަށް ބަޔާންވެ އެނގިފައިވެއެވެ. އަދި ތިޔަބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ މިސާލުތައް ޖައްސަވައިދެއްވީމެވެ.","",""],["","","","وقد مكروا مكرهم وعند الله مكرهم وإن كان مكرهم لتزول منه الجبال","ހަމަކަށަވަރުން، އެއުރެންގެ ރޭވުންތައް ރޭވޫއެވެ. އަދި އެއުރެންގެ ރޭވުންތައްވަނީ، ﷲގެ ހަޒުރަތު ގައެވެ. (އެބަހީ: އެ ރޭވުންތައް ﷲ ދެނެވޮޑިގެންވެތެވެ.) އަދި އެއުރެންގެ ރޭވުންތަކުން ފަރުބަދަތައް ނެއްތައިނުލެވޭހުށްޓެވެ.","",""],["","","","فلا تحسبن الله مخلف وعده رسله إن الله عزيز ذو انتقام","ފަހެ، ﷲ، އެކަލާނގެ ރަސޫލުންނަށް ކުރައްވާފައިވާ ވައުދާ ޚިލާފުވެ ވޮޑިގަންނަވާނެކަމަށް ކަލޭގެފާނު ހީފުޅުނުކުރައްވާ ހުށިކަމެވެ! ހަމަކަށަވަރުން، ﷲއީ، ބަދަލުހިއްޕެވުމުގެވެރި، ޢަޒީޒުވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","يوم تبدل الأرض غير الأرض والسماوات وبرزوا لله الواحد القهار","އެދުވަހުން، ބިން އެހެން ބިމަކަށް، އަދި އުޑުތައް (އެހެން އުޑުތަކަކަށް) ބަދަލުކުރައްވާނެތެވެ. އަދި އެއްކައުވަންތަ، ބާރުވެރިވަންތަ ﷲގެ ހަޒުރަތަށް އެންމެން ނުކުންނާނެތެވެ.","",""],["","","","وترى المجرمين يومئذ مقرنين في الأصفاد","އަދި އެދުވަހުން، ކުށްވެރިންތައް އެކުއެކުގައި ކަސްތަޅު އެޅިފައިވާތީ ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނޫއެވެ.","",""],["","","","سرابيلهم من قطران وتغشى وجوههم النار","އެއުރެންގެ ފޭރާން ވަނީ ކަތުރާނުންނެވެ. އަދި އަލިފާން، އެއުރެންގެ މޫނުތައް ފޮރުވައިލާނެތެވެ.","",""],["","","","ليجزي الله كل نفس ما كسبت إن الله سريع الحساب","(އެއީ) ﷲ، ކޮންމެ ނަފްސަކަށްމެ، އެ ނަފްސެއް ހޯދިކަމެއްގެ ޖަޒާ ދެއްވުމަށްޓަކައެވެ. ހަމަކަށަވަރުން، ﷲއީ، ހިސާބު ބެއްލެވުން އަވަސްވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","هذا بلاغ للناس ولينذروا به وليعلموا أنما هو إله واحد وليذكر أولو الألباب","މި ގުރްއާނަކީ (އެންމެހާ) މީސްތަކުންނަށް އެއިން އިންޒާރުކުރެއްވުމަށްޓަކައި އޮތް އެންގެވުމެކެވެ. އަދި ހަމަކަށަވަރުން، އެކަލާނގެއީ، އެއްކައުވަންތަ ކަލާނގެކަން އެއުރެން ދެނެގަތުމަށާއި، އަދި ބުއްދީގެ އަހުލުވެރިން ނަސޭހަތް ލިބިގަތުމަށްޓަކައެވެ.","",""],["","","","بسم الله الرحمن الرحيم الر تلك آيات الكتاب وقرآن مبين","ا ل ر (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ، ﷲއެވެ.) މިއީ، (ބާވައިލެއްވި) ފޮތުގެ، އަދި ފާޅުވެ ބަޔާންވެގެންވާ ގުރްއާންގެ އާޔަތް ތަކެވެ.","",""],["","","","ربما يود الذين كفروا لو كانوا مسلمين","ކާފިރުވި މީހުން އެއުރެންނީ މުސްލިމު ންކަމުގައި ވީނަމައޭ ހިތައި އެކަމަށް ގިނަގިނައިން އެދެތެވެ.","",""],["","","","ذرهم يأكلوا ويتمتعوا ويلههم الأمل فسوف يعلمون","އެއުރެން ކައިބޮއި، ދުނިޔޭގެ ވަގުތީ އުފާ ލިބިގަތުމަށާއި، ދޮގު އުންމީދުތައް އެއުރެން މަޝްޣޫލުކުރުވުމަށް، ކަލޭގެފާނު އެއުރެން ދޫކޮށްލައްވާށެވެ! ފަހެ (އެކަންތަކުގެ ނަތީޖާ) އެއުރެންނަށް ފަހުން އެނގޭހުށްޓެވެ.","",""],["","","","وما أهلكنا من قرية إلا ولها كتاب معلوم","އެ ރަށަކަށް ކަނޑައެޅި އެނގިގެންވާ މުއްދަތެއްވާ ޙާލުގައި މެނުވީ، ތިމަންރަސްކަލާނގެ އެއްވެސް ރަށެއް ހަލާކެއް ނުކުރައްވަމެވެ.","",""],["","","","ما تسبق من أمة أجلها وما يستأخرون","އެއްވެސް އުއްމަތަކަށް، އެ އުއްމަތްގެ އަޖަލު އިހެއްނުކުރައްވާނެއެވެ. އަދި ފަހެއްވެސް ނުމެކުރައްވާނޭމެއެވެ.","",""],["","","","وقالوا يا أيها الذي نزل عليه الذكر إنك لمجنون","އެއުރެން ބުނެފޫއެވެ. އޭ ގުރްއާން އެބޭކަލެއްގެ މައްޗަށް ބާވައިލެއްވި ކަލޭގެފާނެވެ! ހަމަކަށަވަރުން، ކަލޭގެފާނީ، މޮޔައެއްކަން ކަށަވަރެވެ.","",""],["","","","لو ما تأتينا بالملائكة إن كنت من الصادقين","ކަލޭގެފާނު ތެދުބުނާމީހުންގެ ތެރެއިންވާނަމަ، ތިމަންމެންގެ ގާތަށް ކަލޭގެފާނު މަލާއިކަތުން ނުގެންނަވަނީ ކީއްވެގެންތޯއެވެ؟","",""],["","","","ما ننزل الملائكة إلا بالحق وما كانوا إذا منظرين","ހައްގު ބަސްފުޅާއިގެން މެނުވީ، ތިމަންރަސްކަލާނގެ މަލާއިކަތުން ބާވައެއް ނުލައްވަމެވެ. އަދި އެ ހިނދު ފަސްކުރައްވާނޭ ބަޔަކުކަމުގައި އެއުރެން ނުވެއެވެ.","",""],["","","","إنا نحن نزلنا الذكر وإنا له لحافظون","ހަމަކަށަވަރުން، ގުރްއާން ބާވައިލެއްވީ، ތިމަންރަސްކަލާނގެއެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، އެ ގުރްއާން ރައްކާތެރި ކުރައްވާހުށީމެވެ.","",""],["","","","ولقد أرسلنا من قبلك في شيع الأولين","ހަމަކަށަވަރުން، އިސްވެދިޔަ އުއްމަތްތަކުގެ ތެރެއަށް ކަލޭގެފާނުގެ ކުރިންވެސް ތިމަންރަސްކަލާނގެ ރަސޫލުން ފޮނުއްވީމެވެ.","",""],["","","","وما يأتيهم من رسول إلا كانوا به يستهزئون","އަދި އެބޭކަލަކަށް އެއުރެން ފުރައްސާރަ ކުރާކަމުގައި ނުވާ އެއްވެސް ރަސޫލަކު އެއުރެންގެ ގާތަކަށް ވަޑައެއް ނުގަންނަވަތެވެ.","",""],["","","","كذلك نسلكه في قلوب المجرمين","ކުށްވެރިންގެ ހިތްތަކަށް ތިމަންރަސްކަލާނގެ އެކަން ވައްދަވަނީ އެފަދައިންނެވެ.","",""],["","","","لا يؤمنون به وقد خلت سنة الأولين","އެއުރެން އެކަލޭގެފާނަކަށް އީމާނެއް ނުވާނެތެވެ. އިސްވެދިޔަ މީހުންނަށް ވެގެންދިޔަގޮތް، ފާއިތުވެ ހިނގައްޖެކަން ކަށަވަރެވެ.","",""],["","","","ولو فتحنا عليهم بابا من السماء فظلوا فيه يعرجون","އެއުރެންނަށް ތިމަންރަސްކަލާނގެ އުޑުން ދޮރެއް ހުޅުއްވައިދެއްވައި، އެ ދޮރުން އެއުރެން (އުޑަށް) އަރައަރާތިބި ކަމުގައިވީނަމަވެސް ހަމަކަށަވަރުން، ތިމަންމެންގެ ލޯތައްވަނީ މަސްތުކުރައްވާފައޭ، އެއުރެން ބުނީސްކަން ކަށަވަރެވެ. އަދި ކިއެއްތަ! ތިމަންމެންނީ ޖާދޫގައި ޖެހިފައިވާ ބަޔެކެވެ.","",""],["","","","لقالوا إنما سكرت أبصارنا بل نحن قوم مسحورون","އެއުރެންނަށް ތިމަންރަސްކަލާނގެ އުޑުން ދޮރެއް ހުޅުއްވައިދެއްވައި، އެ ދޮރުން އެއުރެން (އުޑަށް) އަރައަރާތިބި ކަމުގައިވީނަމަވެސް ހަމަކަށަވަރުން، ތިމަންމެންގެ ލޯތައްވަނީ މަސްތުކުރައްވާފައޭ، އެއުރެން ބުނީސްކަން ކަށަވަރެވެ. އަދި ކިއެއްތަ! ތިމަންމެންނީ ޖާދޫގައި ޖެހިފައިވާ ބަޔެކެވެ.","",""],["","","","ولقد جعلنا في السماء بروجا وزيناها للناظرين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، އުޑުގައި ބުރުޖު ތަކެއް ލެއްވީމެވެ. އަދި ބަލާ މީހުންނަށްޓަކައި، ތިމަންރަސްކަލާނގެ އެ އުޑު ޒީނަތްތެރިކުރެއްވީމެވެ.","",""],["","","","وحفظناها من كل شيطان رجيم","އަދި ﷲގެ ރަހުމަތުން ބޭރުކުރައްވާފައިވާ ކޮންމެ ޝައިތާނެއްގެ ކިބައިން، ތިމަންރަސްކަލާނގެ އެ އުޑު ރައްކާތެރި ކުރެއްވީމެވެ.","",""],["","","","إلا من استرق السمع فأتبعه شهاب مبين","އެހުމުން ވައްކަންކުޅަ ޝައިތާނަކު މެނުވީއެވެ. ފަހެ، ފާޅުވެގެންވާ ގިނިހިލައެއް އެ ޝައިތާނެއްގެ ފަހަތުން އަންނަހުށްޓެވެ.","",""],["","","","والأرض مددناها وألقينا فيها رواسي وأنبتنا فيها من كل شيء موزون","އަދި ތިމަންރަސްކަލާނގެ ބިން ފެތުރުއްވީމެވެ. އަދި ހަރުލައި ހުންނަ ފަރުބަދަތައް، އެ ބިމުގައި ލެއްވީމެވެ. އަދި މިންވަރު ކަނޑައެޅި އެނގިގެންވާ ކޮންމެ އެއްޗެއް، އެ ބިމުން ތިމަންރަސްކަލާނގެ ފެޅުއްވީމެވެ.","",""],["","","","وجعلنا لكم فيها معايش ومن لستم له برازقين","އަދި ތިޔަބައިމީހުންނަށްޓަކައްޔާއި، އެ ތަކެއްޗަށް ތިޔަބައިމީހުން ރިޒްގު ދޭ ކަމުގައި ނުވާ ތަކެއްޗަށްޓަކައި، ދިރިއުޅުމުގެ ވަސީލަތްތައް ތިމަންރަސްކަލާނގެ އެ ބިމުގައި ލެއްވީމެވެ.","",""],["","","","وإن من شيء إلا عندنا خزائنه وما ننزله إلا بقدر معلوم","އެ އެއްޗެއްގެ ޚަޒާނާތައް ތިމަންރަސްކަލާނގެ ހަޒުރަތުގައި ނުވާ އެއްވެސް އެއްޗެއް ނުވެއެވެ. އަދި ކަނޑައެޅި އެނގިގެންވާ މިންވަރަކަށް މެނުވީ، ތިމަންރަސްކަލާނގެ އެ އެއްޗެއް ބާވައެއް ނުލައްވަމެވެ.","",""],["","","","وأرسلنا الرياح لواقح فأنزلنا من السماء ماء فأسقيناكموه وما أنتم له بخازنين","ތިމަންރަސްކަލާނގެ ވައިރޯޅިތައް ފޮނުއްވީމެވެ. (ވިލާތަކާއި ގަސްގަހާގެހި) ތަލްގީޙްކުރާ (އެބަހީ: ދަރިމައިކުރާ) އެއްޗެއްގެ ގޮތުގައެވެ. އަދި ތިމަންރަސްކަލާނގެ އުޑުން ވާރޭވެއްސެވީމެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް އެ ފެން ބޯންދެއްވީމެވެ. އަދި އެ ފެން ރައްކާކޮށް ޚަޒާނާކުރެވޭނެ ބަޔަކު ކަމުގައި ތިޔަބައިމީހުން ނުވެތެވެ.","",""],["","","","وإنا لنحن نحيي ونميت ونحن الوارثون","އަދި ހަމަކަށަވަރުން، ދިރުއްވަނީވެސް، އަދި މަރުގަންނަވަނީވެސް ތިމަންރަސްކަލާނގެއެވެ. އަދި ދެމިހުންނަނިވި ވާރުތަވެރިޔަކީވެސް ތިމަންރަސްކަލާނގެއެވެ. (އެބަހީ: އެންމެހާ ތަކެތި ފަނާވެދިއުމަށްފަހުވެސް ދިރިދެމިވޮޑިގެންވަނީ ތިމަންރަސްކަލާނގެއެވެ.)","",""],["","","","ولقد علمنا المستقدمين منكم ولقد علمنا المستأخرين","އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ތެރެއިން ކުރީގެ (ޖީލުތަކުގެ) މީހުން ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގެންވަމެވެ. އަދި ހަމަކަށަވަރުން، ފަހުން އަންނާނޭ މީހުންވެސް ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގެންވަމެވެ.","",""],["","","","وإن ربك هو يحشرهم إنه حكيم عليم","އަދި ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެއުރެން މަހުޝަރަށް ފޮނުއްވާ ހުށްޓެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ޙަކީމްވަންތަ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ولقد خلقنا الإنسان من صلصال من حمإ مسنون","ތަޣައްޔަރު ވެފައިވާ ކަޅުކުލައިގެ ކިސަޑުން އުފެދިގެންއައި މަށިން ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އިންސާނާ ހެއްދެވީމެވެ.","",""],["","","","والجان خلقناه من قبل من نار السموم","އަދި އޭގެކުރިން ދުމެއްނެތް އަލިފާނުން ތިމަންރަސްކަލާނގެ ޖިންނީން ހެއްދެވީމެވެ.","",""],["","","","وإذ قال ربك للملائكة إني خالق بشرا من صلصال من حمإ مسنون","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ މަލާއިކަތުންނަށް ވަހީކުރެއްވި ހިނދު ހަނދުމަކުރައްވާށެވެ! ތަޣައްޔަރު ވެފައިވާ ކަޅުކުލައިގެ ކިސަޑުން އުފެދިގެންއައި މަށިން ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އިންސާނަކު ހައްދަވާހުށީމެވެ.","",""],["","","","فإذا سويته ونفخت فيه من روحي فقعوا له ساجدين","ފަހެ، ތިމަންރަސްކަލާނގެ އެ އިންސާނާ (އެބަހީ: އާދަމުގެފާނު) ހައްދަވައި، ފުރިހަމަކުރައްވައި، ތިމަންރަސްކަލާނގެ ރޫޙުފުޅުން އެ އިންސާނާއަށް ފުމެލައްވައިފި ހިނދު، ތިޔަބައިމީހުން އޭނާއަށްޓަކައި ސަޖިދަށް ތިރިވާހުށިކަމެވެ!","",""],["","","","فسجد الملائكة كلهم أجمعون","ފަހެ، މަލާއިކަތުން އެ އެންމެން އެކުގައި ސަޖިދަކުރައްވައިފޫއެވެ.","",""],["","","","إلا إبليس أبى أن يكون مع الساجدين","އިބްލީސް މެނުވީއެވެ. ސަޖިދަކުރި މަލާއިކަތުންނާ އެކުގައިވުމަށް އިބްލީސް ނުރުހި، އެކަމުން މަނާވެގެންފިއެވެ.","",""],["","","","قال يا إبليس ما لك ألا تكون مع الساجدين","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. އޭ އިބްލީސެވެ! ސަޖިދަކުރި މަލާއިކަތުންނާ އެކުގައި ނުވުމަށް ކަލޭގެއަށް މެދުވެރިވީ ކޮންކަމެއް ހެއްޔެވެ؟","",""],["","","","قال لم أكن لأسجد لبشر خلقته من صلصال من حمإ مسنون","އެކަލޭގެ ދެންނެވިއެވެ. ތަޣައްޔަރު ވެފައިވާ ކަޅުކުލައިގެ ކިސަޑުން އުފެދިގެން އައި މަށިން އިބަރަސްކަލާނގެ ހެއްދެވި އިންސާނަކަށް ސަޖިދަކުރާކަށް ތިމަން ނެތީމެވެ.","",""],["","","","قال فاخرج منها فإنك رجيم","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ފަހެ، ކަލޭގެ އެތަނުން (އެބަހީ: ސުވަރުގެއިން) ނުކުންނާށެވެ! ފަހެ، ހަމަކަށަވަރުން، ކަލޭގެވަނީ، ރަހުމަތުން ބޭރުކުރައްވާފައެވެ.","",""],["","","","وإن عليك اللعنة إلى يوم الدين","އަދި ހަމަކަށަވަރުން، ގިޔާމަތް ދުވަހަށް ދާނދެން ކަލޭގެ މައްޗަށް ލައުނަތް ހުށްޓެވެ.","",""],["","","","قال رب فأنظرني إلى يوم يبعثون","އެކަލޭގެ ދެންނެވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ފަހެ، އެއުރެން (އަލުން ދިރުއްވައި މަހުޝަރަށް) ފޮނުއްވާނޭ ދުވަހަށް ދާނދެން ތިމަން އަޅާޔަށް މުހުލަތް ދެއްވާނދޭވެ!","",""],["","","","قال فإنك من المنظرين","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ފަހެ، ހަމަކަށަވަރުން، ކަލޭގެވަނީ، މުހުލަތް ދެއްވާފައިވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["","","","إلى يوم الوقت المعلوم","ވަގުތު ކަނޑައެޅި އެނގިގެންވާ ދުވަހަށް ދާނދެނެވެ.","",""],["","","","قال رب بما أغويتني لأزينن لهم في الأرض ولأغوينهم أجمعين","އެކަލޭގެ ދެންނެވިއެވެ. ތިމަންއަޅާގެ ވެރިރަސްކަލާކޮ! އިބަރަސްކަލާނގެ ތިމަންއަޅާ މަގުފުރެއްދެވިކަމުގެ ސަބަބުން، ނުބައިކަމުގެ މަގު، ހަމަކަށަވަރުން، އެއުރެންނަށް ބިމުގައި ތިމަންއަޅާ ޒީނަތްތެރިކޮށްދޭހުށީމެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންއަޅާ އެ އެންމެން މަގުފުރައްދާހުށީމެވެ.","",""],["","","","إلا عبادك منهم المخلصين","އެއުރެންގެ ތެރެއިން، އިބަރަސްކަލާނގެ އަޅުންކުރެ ޚިޔާރުކުރައްވާފައިވާ މީހުން މެނުވީއެވެ.","",""],["","","","قال هذا صراط علي مستقيم","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. މިއީ، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް އޮތް ސީދާވެގެންވާ ތެދުމަގެވެ.","",""],["","","","إن عبادي ليس لك عليهم سلطان إلا من اتبعك من الغاوين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އަޅުންގެ މައްޗަށް ކަލޭގެއަކަށް ބާރު ލިބިގެނެއްނުވެއެވެ. މަގުފުރެދިގެންވާ މީހުންގެތެރެއިން ކަލޭގެއަށް ތަބާވާ މީހުން މެނުވީއެވެ.","",""],["","","","وإن جهنم لموعدهم أجمعين","އަދި ހަމަކަށަވަރުން، ނަރަކައަކީ، އެ އެންމެންނަށް ﷲ ވައުދުކުރައްވާފައިވާ ތަނެއްކަން ކަށަވަރެވެ.","",""],["","","","لها سبعة أبواب لكل باب منهم جزء مقسوم","އެ ނަރަކައަށް ހަތް ދޮރުވެއެވެ. އެއިން ކޮންމެ ދޮރަކަށް ކަނޑައެޅިގެންވާ ބައެއްވެއެވެ.","",""],["","","","إن المتقين في جنات وعيون","ހަމަކަށަވަރުން، ތަގުވާވެރިން ވަނީ ސުވަރުގެތަކާއި، ފެންއާރުތަކުގެ ނިއުމަތް ގައެވެ.","",""],["","","","ادخلوها بسلام آمنين","(އެއުރެންނަށް އަންގަވާނެތެވެ.) ތިޔަބައިމީހުން ސަލާމަތްކަމާއެކު، އަމާންކަން ލިބިގެންވާ ޙާލު އެތަނަށް ވަންނާށެވެ!","",""],["","","","ونزعنا ما في صدورهم من غل إخوانا على سرر متقابلين","އަދި ތިމަންރަސްކަލާނގެ، އެއުރެންގެ ހިތްތަކުގައިވާ ހަސަދަވެރިކަން ވަކިކުރެއްވީމެވެ. ދާންތަކެއްގެ މަތީގައި އެކަކު އަނެކަކަށް ކުރިމަތިލައިތިބޭ އަޚު ންތަކެއްގެ ގޮތުގައެވެ.","",""],["","","","لا يمسهم فيها نصب وما هم منها بمخرجين","އެއުރެންނަކަށް އެތާނގައި އެއްވެސް ވަރުބަލިކަމެއް ނުޖެހޭނެތެވެ. އަދި އެ ތަނުން ނެރުއްވާނެ ބަޔަކު ކަމުގައިވެސް އެއުރެން ނުމެވޭމެއެވެ.","",""],["","","","نبئ عبادي أني أنا الغفور الرحيم","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެކަމުގައި، ތިމަންރަސްކަލާނގެ އަޅުތަކުންނަށް ކަލޭގެފާނު ޚަބަރު ދެއްވާށެވެ!","",""],["","","","وأن عذابي هو العذاب الأليم","އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އަޒާބެއީ، ވޭންދެނިވި އަޒާބެއް ކަމަށްވެސްމެއެވެ.","",""],["","","","ونبئهم عن ضيف إبراهيم","އަދި އިބްރާހީމްގެފާނުގެ މެހުމާނުންގެ ވާހަކަ، ކަލޭގެފާނު އެބައިމީހުންނަށް ކިޔައިދެއްވާށެވެ!","",""],["","","","إذ دخلوا عليه فقالوا سلاما قال إنا منكم وجلون","އެ މެހުމާނުން އެކަލޭގެފާނުގެ އަރިހަށް ވަންހިނދެވެ. އެ ހިނދު އެއުރެން ދެންނެވޫއެވެ. ސަލާމް ހުށްޓެވެ! އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިމަންމެން ތިޔަބައިމީހުންދެކެ ބިރުގަނެތެވެ.","",""],["","","","قالوا لا توجل إنا نبشرك بغلام عليم","އެ މެހުމާނުން ދެންނެވޫއެވެ. ކަލޭގެފާނު ބިރުފުޅުގެން ވަޑައިނުގަންނަވާށެވެ! ހަމަކަށަވަރުން، އިލްމުވެރި ދަރިކަލަކު، ލިބިވަޑައިގަންނަވާނެކަމުގެ އުފާވެރި ޚަބަރު، ތިމަންމެން ކަލޭގެފާނަށް ދެމުއެވެ.","",""],["","","","قال أبشرتموني على أن مسني الكبر فبم تبشرون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިމަން މުސްކުޅިވީހިނދު، ތިޔަބައިމީހުން އުފާވެރިކަމުގެ ޚަބަރު ތިމަންނާއަށް ދެނީހެއްޔެވެ؟ އުފާވެރިކަމުގެ ޚަބަރު ތިޔަބައިމީހުން ތިޔަދެނީ ފަހެ، ކޮންކަމެއްގެ ވާހަކައިން ހެއްޔެވެ؟","",""],["","","","قالوا بشرناك بالحق فلا تكن من القانطين","އެ މެހުމާނުން ދެންނެވޫއެވެ. ތިމަންމެން ކަލޭގެފާނަށް އުފާވެރިކަމުގެ ޚަބަރު މިދިނީ، ހައްގު ތެދުބަހުންނެވެ. ފަހެ، އުންމީދުކަނޑާލާމީހުންގެ ތެރެއިން ކަލޭގެފާނު ވެވަޑައިނުގަންނަވާށެވެ!","",""],["","","","قال ومن يقنط من رحمة ربه إلا الضالون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. މަގުފުރެދިގެންވާ މީހުން މެނުވީ، އެ މީހެއްގެ ވެރިރަސްކަލާނގެ ރަހުމަތާމެދު، އުންމީދުކަނޑާލާނީ ފަހެ، ކާކުހެއްޔެވެ؟","",""],["","","","قال فما خطبكم أيها المرسلون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ ފޮނުއްވާފައިވާ މަލާއިކަތުންނޭވެ! ފަހެ، ތިޔަބޭކަލުން ފޮނުއްވީ ކޮންކަމަކާތޯއެވެ؟","",""],["","","","قالوا إنا أرسلنا إلى قوم مجرمين","އެބޭކަލުން ދެންނެވޫއެވެ. ހަމަކަށަވަރުން، ތިމަންމެން ފޮނުއްވާފައިވަނީ ކުށްވެރި ގައުމެއްގެ މީހުންގެ ގާތަށެވެ.","",""],["","","","إلا آل لوط إنا لمنجوهم أجمعين","ލޫޠުގެފާނުގެ އަހުލުވެރިން މެނުވީއެވެ. ހަމަކަށަވަރުން، ތިމަންމެން އެ ހުރިހާ އެންމެން ސަލާމަތްކުރާ ހުށީމުއެވެ.","",""],["","","","إلا امرأته قدرنا إنها لمن الغابرين","އެކަލޭގެފާނުގެ އަނބިކަނބަލުން މެނުވީއެވެ. ތިމަންމެން މިންވަރު ކޮށްފައިވަނީ، ހަމަކަށަވަރުން، އެކަނބުލޭގެއަކީ، އަޒާބުގެ ތެރެއަށް ދޫކުރައްވާފައިވާ މީހުންގެ ތެރެއިންވާ މީހެއް ކަމުގައެވެ.","",""],["","","","فلما جاء آل لوط المرسلون","ފަހެ، ފޮނުއްވާފައިވާ މަލާއިކަތުން ލޫޠުގެފާނުގެ އަހުލުވެރިންގެ ގާތަށް ވަޑައިގަތްހިނދު އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަކީ، (ތިމަންކަލޭގެފާނަށް) އެނގިގެންނުވާ ބަޔެކެވެ.","",""],["","","","قال إنكم قوم منكرون","ފަހެ، ފޮނުއްވާފައިވާ މަލާއިކަތުން ލޫޠުގެފާނުގެ އަހުލުވެރިންގެ ގާތަށް ވަޑައިގަތްހިނދު އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަކީ، (ތިމަންކަލޭގެފާނަށް) އެނގިގެންނުވާ ބަޔެކެވެ.","",""],["","","","قالوا بل جئناك بما كانوا فيه يمترون","އެބޭކަލުން ދެންނެވޫއެވެ. އަދި ކީއްތޯއެވެ؟ ތިމަންމެން ކަލޭގެފާނުގެ އަރިހަށް މިއައީ، އެއުރެން އެކަމާމެދު ޝައްކު ކޮށްއުޅުނު ކަންތަކާއިގެންނެވެ.","",""],["","","","وأتيناك بالحق وإنا لصادقون","އަދި ތިމަންމެން ކަލޭގެފާނުގެ އަރިހަށް އައީ، ހައްގު ބަސްފުޅާއިގެންނެވެ. ހަމަކަށަވަރުން، ތިމަންމެންނީ، ތެދުބުނާބަޔަކުކަން ކަށަވަރެވެ.","",""],["","","","فأسر بأهلك بقطع من الليل واتبع أدبارهم ولا يلتفت منكم أحد وامضوا حيث تؤمرون","ފަހެ، ކަލޭގެފާނުގެ އަހުލުވެރިންނާއިގެން ރޭގަނޑުން ބައެއްގައި ކަލޭގެފާނު ދަތުރުކުރައްވައި، ހިންގަވާށެވެ! އަދި ކަލޭގެފާނު އެއުރެންގެ ފަހަތުން ވަޑައިގަންނަވާށެވެ! އަދި ތިޔަބައިމީހުންކުރެ އެކަކުވެސް ފަސްއެނބުރި ނުބަލާށެވެ! އަދި ތިޔަބައިމީހުންނަށް، އަމުރުކުރައްވާފައިވާ ތަނަށް، ތިޔަބައިމީހުންދާށެވެ!","",""],["","","","وقضينا إليه ذلك الأمر أن دابر هؤلاء مقطوع مصبحين","އެކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ އެކަންތައް ނިޔާކުރައްވައި އެންގެވީމެވެ. (އެއީ) ހަމަށަވަރުން، އެއުރެންނީ ފަތިސްވެގެންއަންނަ ވަގުތުގައި، މުލުން ކެނޑި ނެތިދާނޭ ބަޔެކެވެ.","",""],["","","","وجاء أهل المدينة يستبشرون","(އަލަށް ބަޔަކު ރަށަށް އައިވާހަކަ އިވި) އުފާކުރާ ޙާލު، ރަށުގެ އަހުލުވެރިން އައޫއެވެ.","",""],["","","","قال إن هؤلاء ضيفي فلا تفضحون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، މިބައިމީހުންނަކީ، ތިމަންގެ މެހުމާނުންނެވެ. ފަހެ، ތިޔަބައިމީހުން ތިމަން ފަޟީޙަތް ނުކުރާށެވެ!","",""],["","","","واتقوا الله ولا تخزون","އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ތިމަން ދެރަކޮށް ލަދުގަންނަވައި ނުލާށެވެ!","",""],["","","","قالوا أولم ننهك عن العالمين","އެއުރެން ދެންނެވޫއެވެ. (ބޭރު) އެއްވެސްމީހަކާ ބައްދަލުވެ އުޅުއްވުން ތިމަންމެން ކަލޭގެފާނަށް ނަހީނުކުރަމުތޯއެވެ؟","",""],["","","","قال هؤلاء بناتي إن كنتم فاعلين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން އެ ކަންތައްކުރާ ކަމުގައިވަނީނަމަ، (އެބަހީ: އެދުންފުއްދައިއުޅެން ބޭނުންނަމަ، ޝަރުއީ ހަމަތަކުން ކާވެނިވުމަށް) ތިމަންގެ އަންހެންދަރިން (އެބަހީ: ގައުމުގެ އަންހެންދަރިން) މިތިބީއެވެ.","",""],["","","","لعمرك إنهم لفي سكرتهم يعمهون","ކަލޭގެފާނުގެ ހަޔާތް ޕުޅު ގަންދެއްވައި ވަހީކުރައްވަމެވެ. ހަމަކަށަވަރުން، އެއުރެންވަނީ، އެއުރެންގެ މަސްތުގެތެރޭގައި، ހައިރާންވެ، ދެފުށުއެޅޭ ޙާލު ގައެވެ.","",""],["","","","فأخذتهم الصيحة مشرقين","ފަހެ، އިރުއެރި ވަގުތުގައި ގަދަފަދައަޑު (އައިސް) އެއުރެން ހަލާކުކުރިއެވެ.","",""],["","","","فجعلنا عاليها سافلها وأمطرنا عليهم حجارة من سجيل","ފަހެ، ތިމަންރަސްކަލާނގެ އެ ރަށުގެ، މައްޗަށްއޮތްފުށް ވަތަށްއޮތްފުށްކަމުގައި ލެއްވީމެވެ. އަދި އަލިފާނުން ދޮންކުރައްވާފައިވާ މަށީގެ ހިލައިން ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް ވާރޭ ވެއްސެވީމެވެ.","",""],["","","","إن في ذلك لآيات للمتوسمين","ހަމަކަށަވަރުން، އެކަންތަކުގައި، ވިސްނައި ފިކުރުކުރާ މީހުންނަށް ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","وإنها لبسبيل مقيم","އަދި ހަމަކަށަވަރުން، އެ ރަށްވަނީ ސާބިތުވެ ފެންނަންއޮތް މަގެއްގައިކަން ކަށަވަރެވެ.","",""],["","","","إن في ذلك لآية للمؤمنين","ހަމަކަށަވަރުން، އެކަމުގައި މުއުމިނު ތަކުންނަށް ހެތްކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","وإن كان أصحاب الأيكة لظالمين","އަދި ހަމަކަށަވަރުން، އަލްއައިކަތުގެ އަހުލުވެރިން، އަނިޔާވެރި ބަޔަކު ކަމުގައިވީކަން ކަށަވަރެވެ.","",""],["","","","فانتقمنا منهم وإنهما لبإمام مبين","ފަހެ، ތިމަންރަސްކަލާނގެ އެއުރެންގެ ކިބައިން ބަދަލު ހިއްޕެވީމެވެ. އަދި ހަމަކަށަވަރުން، އެ ދެރަށް (އެބަހީ: ލޫޠު ބާގައިމީހުންގެ ރަށާއި އަލްއައިކަތުގެރަށް) ވަނީ ބަޔާންވެ އެނގިގެންވާ މަގެއްގައިކަން ކަށަވަރެވެ.","",""],["","","","ولقد كذب أصحاب الحجر المرسلين","ހަމަކަށަވަރުން، ޙިޖްރުގެ އަހުލުވެރިން (އެބަހީ: ޘަމޫދު ބާގައިމީހުން) ރަސޫލުން ދޮގުކުޅައޫއެވެ.","",""],["","","","وآتيناهم آياتنا فكانوا عنها معرضين","އަދި އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ހެކިތައް ގެނެސްދެއްވީމެވެ. ފަހެ، އެ ހެކިތަކަށް ފުރަގަސްދޭ ބަޔަކުކަމުގައި އެއުރެންވޫއެވެ.","",""],["","","","وكانوا ينحتون من الجبال بيوتا آمنين","އަދި އަމާންވެގެން ތިބިކަމަށް (ހީކޮށް) ފަރުބަދަތަކުން ކަނޑައިކޮށައިގެން، ގެތައް ހަދާބަޔަކު ކަމުގައި އެއުރެންވޫއެވެ.","",""],["","","","فأخذتهم الصيحة مصبحين","ފަހެ، ފަތިސްވަގުތު، ގަދަފަދަ އަޑު (އައިސް) އެއުރެން ހަލާކުކުރިއެވެ.","",""],["","","","فما أغنى عنهم ما كانوا يكسبون","ފަހެ، އެއުރެން ހޯދައި އުޅުނު ޢަމަލުތައް އެއުރެންނަކަށް އެއްވެސް ކަމެއް ފުއްދައެއް ނުދިނެވެ.","",""],["","","","وما خلقنا السماوات والأرض وما بينهما إلا بالحق وإن الساعة لآتية فاصفح الصفح الجميل","ތިމަންރަސްކަލާނގެ އުޑުތަކާއި، ބިމާއި، އެ ދެމެދުގައިވާހާ ތަކެއްޗެއް، ހައްގު ގޮތުގައި މެނުވީ ނަހައްދަވަމެވެ. އަދި ހަމަކަށަވަރުން، ގިޔާމަތްގެ ވަގުތު އަންނާނެކަން ކަށަވަރެވެ. ފަހެ، ރިވެތިވެގެންވާ ގޮތުގައި ކަލޭގެފާނު މާފުކުރައްވާށެވެ!","",""],["","","","إن ربك هو الخلاق العليم","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، އެންމެހާ ތަކެތި ހައްދަވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ولقد آتيناك سبعا من المثاني والقرآن العظيم","ހަމަކަށަވަރުން، ތަކުރާރުކޮށްކިޔެވޭ ހަތް އާޔަތާއި، މާތްކަން ބޮޑުވެގެންވާ ގުރްއާން، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ދެއްވީމެވެ.","",""],["","","","لا تمدن عينيك إلى ما متعنا به أزواجا منهم ولا تحزن عليهم واخفض جناحك للمؤمنين","އެއުރެންގެތެރެއިން ބަޔަކަށް، ދުނިޔޭގެ އުފަލެއްގެ ގޮތުގައި ތިމަންރަސްކަލާނގެ ދެއްވާފައިވާ ކަންތަކަށް ކަލޭގެފާނުގެ ލޯފުޅު ނުފޯރުއްވަވާށެވެ! އަދި އެއުރެންގެ މައްޗަށް ކަލޭގެފާނު ހިތާމަ ނުކުރައްވާށެވެ! އަދި މުއުމިނުންނަށްޓަކައި، ކަލޭގެފާނުގެ ފިޔަފުޅު ތިރިކުރައްވާށެވެ! (އެބަހީ: މަޑުމައިތިރިވެވަޑައިގަންނަވާށެވެ!)","",""],["","","","وقل إني أنا النذير المبين","އަދި ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނީ، ބަޔާންވެގެންހުރި އިންޒާރުކުރައްވާ ބޭކަލަކީމެވެ.","",""],["","","","كما أنزلنا على المقتسمين","ބައިބައިކުޅަ މީހުންގެ މައްޗަށް، ތިމަންރަސްކަލާނގެ (އަޒާބު) ބާވައިލެއްވި ފަދައިންނެވެ.","",""],["","","","الذين جعلوا القرآن عضين","އެއުރެންނަކީ، ގުރްއާނެއީ، ވަކިވަކިވެގެންވާ ބައިތަކެއްކަމުގައި ހެދި މީހުންނެވެ.","",""],["","","","فوربك لنسألنهم أجمعين","ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ގަންދެއްވައި ވަހީކުރައްވަމެވެ. ތިމަންރަސްކަލާނގެ އެއުރެން އެންމެންނާ ސުވާލުކުރައްވާ ހުށީމެވެ!","",""],["","","","عما كانوا يعملون","އެއުރެން ކޮށްއުޅުނު ޢަމަލު ތަކާ މެދުގައެވެ.","",""],["","","","فاصدع بما تؤمر وأعرض عن المشركين","ފަހެ، ކަލޭގެފާނަށް އަމުރުކުރައްވާގޮތަށް، ފާޅުގައި ދީނަށް ގޮވައިލައްވާށެވެ! އަދި ޝަރީކުކުރާ މީހުންނާ އެއްކިބާވެ ވަޑައިގަންނަވާށެވެ!","",""],["","","","إنا كفيناك المستهزئين","ހަމަކަށަވަރުން، ކަލޭގެފާނަށް ފުރައްސާރަކުރާމީހުންގެ ނުބައިކަމުން ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ރައްކާތެރިކުރައްވާހުށީމެވެ!","",""],["","","","الذين يجعلون مع الله إلها آخر فسوف يعلمون","އެއުރެންނަކީ، ﷲއާއެކު އެހެން އިލާހަކުލައި، ޝަރީކު ކޮށް އުޅުނު މީހުންނެވެ. ނިކަންހުރެ އެއުރެންނަށް އެނގޭހުށްޓެވެ.","",""],["","","","ولقد نعلم أنك يضيق صدرك بما يقولون","ހަމަކަށަވަރުން، އެއުރެން ބުނާ ބުނުމުން ކަލޭގެފާނުގެ ހިތްޕުޅު ދަތިވާކަން، ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގެންވަމެވެ.","",""],["","","","فسبح بحمد ربك وكن من الساجدين","ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް ހަމްދާއެކު ތަސްބީހަ ވިދާޅުވާށެވެ! އަދި ސަޖިދަކުރާ މީހުންގެ ތެރެއިން ކަލޭގެފާނު ވެވަޑައިގަންނަވާށެވެ!","",""],["","","","واعبد ربك حتى يأتيك اليقين","އަދި ކަލޭގެފާނުގެ އަރިހަށް ޔަގީން ވެގެންވާ ކަންތައް (އެބަހީ: މަރު) އަތުވެއްޖައުމަށް ދާނދެން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް އަޅުކަން ކުރައްވާށެވެ!","",""],["","","","بسم الله الرحمن الرحيم أتى أمر الله فلا تستعجلوه سبحانه وتعالى عما يشركون","ﷲގެ އަމުރުފުޅު އަތުވެއްޖެއެވެ. ފަހެ، ތިޔަބައިމީހުން އެކަން އަވަސްވުމަށް ނޭދޭށެވެ! އެއުރެން ޝަރީކު ކޮށް އުޅުނު ތަކެތިން، އެކަލާނގެ ހުސްތާހިރުވެ، މަތިވެރިވެ ވޮޑިގެންވެއެވެ.","",""],["","","","ينزل الملائكة بالروح من أمره على من يشاء من عباده أن أنذروا أنه لا إله إلا أنا فاتقون","އެކަލާނގެ އަޅުތަކުންގެ ތެރެއިން، އެކަލާނގެ އިރާދަކުރައްވާ ބަޔެއްގެ މައްޗަށް، އެކަލާނގެ އަމުރު ފުޅާއެކު، ވަހީއާއިގެން މަލާއިކަތުން ފޮނުއްވަތެވެ. (ވަހީކުރައްވަމުންނެވެ.) ތިޔަބައިމީހުން އިންޒާރުކުރާށެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ މެނުވީ، އިލާހަކު ނުވެއެވެ. ފަހެ، ތިޔަބައިމީހުން ތިމަންރަސްކަލާނގެއަށް ތަގުވާވެރިވާށެވެ!","",""],["","","","خلق السماوات والأرض بالحق تعالى عما يشركون","އެކަލާނގެ އުޑުތަކާއި، ބިން ހައްގު ގޮތުގައި ހެއްދެވިއެވެ. އެއުރެން ޝަރީކުކުރާ ތަކެއްޗަށްވުރެން، އެކަލާނގެ މަތިވެރިވެވޮޑިގެންވެތެވެ.","",""],["","","","خلق الإنسان من نطفة فإذا هو خصيم مبين","މަނިތިއްކަކުން އެކަލާނގެ އިންސާނާ ހެއްދެވިއެވެ. ފަހެ، އެހާރުން އޭނާވަނީ، ފާޅުވެ، ބަޔާންވެގެންވާ ދެކޮޅުވެރިޔަކު ކަމުގައެވެ.","",""],["","","","والأنعام خلقها لكم فيها دفء ومنافع ومنها تأكلون","އަދި އެކަލާނގެ ތިޔަބައިމީހުންނަށްޓަކައި، ނަޢަމް ސޫފި ހެއްދެވިއެވެ. ހީފިލުވުމާއި، އެހެނިހެން މަންފާތައް އެ ތަކެތީގައިވެއެވެ. އަދި އެ ތަކެތިން ތިޔަބައިމީހުން ކައިއުޅެމުއެވެ.","",""],["","","","ولكم فيها جمال حين تريحون وحين تسرحون","އެ ތަކެތި ހަވީރު (ނިދާތަނަށް) ގެންނަ ހިނދުގައްޔާއި، ހެނދުނު (ހުއިހައްޕަން) ނެރޭހިނދު، ތިޔަބައިމީހުންނަށްޓަކައި އެ ތަކެތީގައި ރީތިކަމެއްވެއެވެ.","",""],["","","","وتحمل أثقالكم إلى بلد لم تكونوا بالغيه إلا بشق الأنفس إن ربكم لرءوف رحيم","އަދި ހަށިތަކަށް އުނދަގުލާއި، ވަރުބަލިކަންދީގެން މެނުވީ އެ ރަށަކާ ހަމައަށް ތިޔަބައިމީހުންނަށް ދެވޭކަމަށްނުވާ ރަށަކަށް، އެ ނަޢަމް ސޫފިތައް ތިޔަބައިމީހުންގެ ބުރަތަކެތި އުފުލައިދެއެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއީ، ނުހަނު އޯގާވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","والخيل والبغال والحمير لتركبوها وزينة ويخلق ما لا تعلمون","އަދި އަހާއި، ބަޣުލާއި، ހިމާރު ވެސް ހެއްދެވިއެވެ. އެއީ ތިޔަބައިމީހުން އެ ތަކެއްޗަށް ސަވާރުވުމަށާއި، އަދި ޒީނަތެއްގެ ގޮތުގައެވެ. އަދި ތިޔަބައިމީހުން ނުދަންނަ ތަކެތި އެކަލާނގެ ހައްދަވަތެވެ.","",""],["","","","وعلى الله قصد السبيل ومنها جائر ولو شاء لهداكم أجمعين","ސީދާވެގެންވާ ތެދުމަގު ބަޔާންކޮށްދެއްވުންވަނީ، ﷲއަށެވެ. އަދި އެ މަގުތަކުގެ ތެރެއިން ކަސިޔާރުވެގެންވާ މަގުވެއެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވައިފިނަމަ، ތިޔަބައިމީހުން އެންމެންނަށް ތެދުމަގު ދައްކަވައިފީސްކަން ކަށަވަރެވެ.","",""],["","","","هو الذي أنزل من السماء ماء لكم منه شراب ومنه شجر فيه تسيمون","ތިޔަބައިމީހުންނަށްޓަކައި، އުޑުން ވާރޭފެން ބާވައިލެއްވީ، އެކަލާނގެއެވެ. އެ ފެނުން (ތިޔަބައިމީހުންނަށް) ބުއިމެއްވެއެވެ. އަދި ތިޔަބައިމީހުންގެ ޖަނަވާރުތައް އެއިން ހުއިހައްޕާ ގަސްތަކާއި، ވިނަތައް، އެ ފެނުގެ ސަބަބުން ހެދެއެވެ.","",""],["","","","ينبت لكم به الزرع والزيتون والنخيل والأعناب ومن كل الثمرات إن في ذلك لآية لقوم يتفكرون","އެކަލާނގެ އެ ފެނުގެ ސަބަބުން ގޮވާމާއި، ޒައިތޫނި ގަހާއި، ކަދުރު ރުކާއި، މޭބިސްކަދުރާއި، އެންމެހާ މޭވާގަސްތައް ތިޔަބައިމީހުންނަށްޓަކައި ފަޅުއްވަތެވެ. ހަމަކަށަވަރުން، ފިކުރުކުރާ ބަޔަކަށް އެކަންކަމުގައި ހެތްކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","وسخر لكم الليل والنهار والشمس والقمر والنجوم مسخرات بأمره إن في ذلك لآيات لقوم يعقلون","އަދި އެކަލާނގެ ރެއާއި، ދުވާލާއި، އިރާއި، ހަނދު، ތިޔަބައިމީހުންނަށްޓަކައި ޚިދުމަތް ތެރި ކުރެއްވިއެވެ. އަދި ތަރިތައްވެސް ވަނީ އެކަލާނގެ އަމުރުފުޅުން ޚިދުމަތް ތެރި ކުރައްވާފައެވެ. ހަމަކަށަވަރުން، އެ ހުރިހާ ކަންތަކުގައި ވިސްނާ ބަޔަކަށް ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","وما ذرأ لكم في الأرض مختلفا ألوانه إن في ذلك لآية لقوم يذكرون","އަދި އެ ތަކެތީގެ ކުލަތައް ތަފާތު ގޮތުގައި، ތިޔަބައިމީހުންނަށްޓަކައި ބިމުގައި އެކަލާނގެ އުފައްދަވާފައިވާ ތަކެތިވެސްމެއެވެ. ހަމަކަށަވަރުން، ހަނދުމަކޮށް އުޅޭބަޔަކަށް އެކަމުގައި ހެތްކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","وهو الذي سخر البحر لتأكلوا منه لحما طريا وتستخرجوا منه حلية تلبسونها وترى الفلك مواخر فيه ولتبتغوا من فضله ولعلكم تشكرون","އަދި ތިޔަބައިމީހުންނަށްޓަކައި، ކަނޑު ޚިދުމަތް ތެރިކުރެއްވީ އެކަލާނގެއެވެ. (އެއީ) ތިޔަބައިމީހުން އެ ކަނޑުން ތާޒާ މަސް ކެއުމަށްޓަކައެވެ. އަދި ތިޔަބައިމީހުން އަޅައިއުޅޭ ގަހަނާ، އެ ކަނޑުން ނެރެ، ނެގުމަށްޓަކައެވެ. އަދި އެ ކަނޑުގައި ގޮސް އައިސްވާ އުޅަނދުތައް ތިބާ ދެކޭނޫއެވެ. އަދި (އެއީ) ތިޔަބައިމީހުން އެކަލާނގެ ފަޟްލު ވަންތަކަމުން (ދެއްވުމަށް) އެދިގަތުމަށްޓަކައެވެ. އަދި ތިޔަބައިމީހުން ޝުކުރުކުރުމަށްޓަކައެވެ.","",""],["","","","وألقى في الأرض رواسي أن تميد بكم وأنهارا وسبلا لعلكم تهتدون","އަދި ތިޔަބައިމީހުންނާއިގެން އެ ބިން، ތެޅިފޮޅިގެންފާނެ ކަމަށްޓަކައި، ހަރުލައި ހުންނަ ފަރުބަދަތައް، ބިމުގައި އެކަލާނގެ ލެއްވިއެވެ. އަދި ކޯރުތަކާއި މަގުތައް ލެއްވިއެވެ. (އެއީ) ތިޔަބައިމީހުންނަށް މަގު އެނގުމަށްޓަކައެވެ.","",""],["","","","وعلامات وبالنجم هم يهتدون","އަދި (މަގު ފާހަގަކުރެވޭ) ފާހަގަތަކެއް ލެއްވިއެވެ. އަދި ތަރިތަކުންވެސް އެއުރެން މަގު ހޯދައިގަނެތެވެ.","",""],["","","","أفمن يخلق كمن لا يخلق أفلا تذكرون","ފަހެ (އެންމެހާ ތަކެތި) ހައްދަވާ ކަލާނގެއާއި (އެއްޗެއް) ނަހަދާ ފަރާތަކާ އެއްފަދަވާނޭ ހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުން ހަނދުމަނުކުރަނީ ހެއްޔެވެ؟","",""],["","","","وإن تعدوا نعمة الله لا تحصوها إن الله لغفور رحيم","ތިޔަބައިމީހުން ﷲގެ ނިއުމަތް ހިމަނައި، އަދަދުކުރަން އުޅުނަސް، ތިޔަބައިމީހުންނަކަށް އެ ނިއުމަތެއް ނުހިމެނޭނެއެވެ. ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","والله يعلم ما تسرون وما تعلنون","އަދި ތިޔަބައިމީހުން ސިއްރުކުރާ ކަންތަކާއި، ފާޅުކުރާ ކަންތައް ﷲ ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","والذين يدعون من دون الله لا يخلقون شيئا وهم يخلقون","އަދި ﷲ ފިޔަވައި އެއުރެން ދުއާ ކޮށް އަޅުކަންކޮށް އުޅޭ ތަކެތި، އެއްވެސް އެއްޗެއް ނަހަދަތެވެ. އަދި ޚުދު އެ ތަކެއްޗަކީ، ހައްދަވާފައިވާ ތަކެއްޗެވެ.","",""],["","","","أموات غير أحياء وما يشعرون أيان يبعثون","(އެއީ) މަރުވެފައިވާ، ދިރުމެއްނުވާ ތަކެއްޗެވެ. އަދި އެއުރެން (އެހެން ދިރުމަކަށް) ފޮނުއްވާނެ އިރެއް އެ ތަކެއްޗަކަށް ނޭނގެތެވެ.","",""],["","","","إلهكم إله واحد فالذين لا يؤمنون بالآخرة قلوبهم منكرة وهم مستكبرون","ތިޔަބައިމީހުންގެ އިލާހަކީ، އެއްކައުވަންތަ އިލާހެވެ. ފަހެ، އާޚިރަތަށް އީމާން ނުވާ މީހުންނަކީ، އެއުރެންގެ ހިތްތައް އެކަމަށް އިންކާރުކުރާ މީހުންނެވެ. އަދި އެއުރެންނީ ބޮޑާވެގެންވާ ބަޔެކެވެ.","",""],["","","","لا جرم أن الله يعلم ما يسرون وما يعلنون إنه لا يحب المستكبرين","ޝައްކެއްނެތެވެ. ހަމަކަށަވަރުން، އެއުރެން ސިއްރުކުރާ ކަންތަކާއި، ފާޅުކުރާ ކަންތައް ﷲ ދެނެވޮޑިގެންވެތެވެ. ހަމަކަށަވަރުން، ބޮޑާވެގަންނަ މީހުންދެކެ، އެކަލާނގެ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["","","","وإذا قيل لهم ماذا أنزل ربكم قالوا أساطير الأولين","ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ބާވައިލެއްވީ ކޮންއެއްޗެއްހޭ، އެއުރެންނަށް ބުނެފިނަމަ، އެއުރެން ބުނެތެވެ. އެވޭލާ މީހުން ދައްކައި އުޅުނު ފުލޯކު ވާހަކަތަކެވެ.","",""],["","","","ليحملوا أوزارهم كاملة يوم القيامة ومن أوزار الذين يضلونهم بغير علم ألا ساء ما يزرون","(އެއީ) ގިޔާމަތް ދުވަހުން އެއުރެންގެ ކުށްތައް ފުރިހަމައަށް އެއުރެން އުފުލުމަށްޓަކައެވެ. އަދި އެނގުމެއްނެތި، އެއުރެން މަގުފުރައްދާ މީހުންގެ ކުށްތަކުގެ ތެރެއިން ބައެއް (އެއުރެން އުފުލުމަށްޓަކައި) ވެސް މެއެވެ. ދަންނާށެވެ! އެއުރެން އުފުލާ ކުށްތަކުގެ ނުބައިކަމާއެވެ!","",""],["","","","قد مكر الذين من قبلهم فأتى الله بنيانهم من القواعد فخر عليهم السقف من فوقهم وأتاهم العذاب من حيث لا يشعرون","ހަމަކަށަވަރުން، އެއުރެންގެ ކުރީގެ މީހުން މަކަރުހެދޫއެވެ. ފަހެ، ﷲ، އެއުރެންގެ ބިނާ، ބިންގަލުން ނެތިކުރެއްވުމަށް އިރާދަކުރެއްވިއެވެ. ދެން އެއުރެންގެ (ބޯ) މަތިން، އެއުރެންގެ މައްޗަށް، ފުރާޅު ވެއްޓިގެން ދިޔައެވެ. އަދި އެއުރެން ހީވެސްނުކުރާ ގޮތްގޮތުން، އެއުރެންނަށް އަޒާބު އައެވެ.","",""],["","","","ثم يوم القيامة يخزيهم ويقول أين شركائي الذين كنتم تشاقون فيهم قال الذين أوتوا العلم إن الخزي اليوم والسوء على الكافرين","ދެން ގިޔާމަތް ދުވަހުން، އެކަލާނގެ އެއުރެން ނިކަމެތި ކުރައްވާނެތެވެ. އަދި ވަހީކުރައްވާނެތެވެ. ތިމަންރަސްކަލާނގެއަށްވާ ޝަރީކުން ކަމުގައި ހަދައި (އަދި) އެ ތަކެއްޗާމެދު (މުއުމިނުންނާ) ތިޔަބައިމީހުން ދެކޮޅުވެރިވެ އުޅުނު ޝަރީކުން ކޮބައިހެއްޔެވެ؟ އިލްމު ލިބިގެންވާ މީހުން (އެ ދުވަހުން) ދަންނަވާނެތެވެ. ހަމަކަށަވަރުން، ނިކަމެތިކަމާއި، ނުބައިކަން މިއަދު އޮތީ ކާފިރުންގެ މައްޗަށެވެ.","",""],["","","","الذين تتوفاهم الملائكة ظالمي أنفسهم فألقوا السلم ما كنا نعمل من سوء بلى إن الله عليم بما كنتم تعملون","(އެއީ) އެއުރެންގެ ނަފްސުތަކަށް އަނިޔާކުރާ ޙާލު، މަލާއިކަތުން އެއުރެން މަރުގަންނަވާ މީހުންނެވެ. ފަހެ، އެއުރެން މަލާއިކަތުންނަށް ބޯލަނބައި ކިޔަމަންވާން ޖެހުނެވެ. (އަދި ދެންނެވިއެވެ.) ތިމަންމެން އެއްވެސް ނުބައިކަމެއް ކޮށެއް ނޫޅެމުއެވެ. އެހެންނަކުން ނޫނެވެ. ހަމަކަށަވަރުން، ﷲއީ، ތިޔަބައިމީހުން ކޮށްއުޅުނު ޢަމަލުތައް، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","فادخلوا أبواب جهنم خالدين فيها فلبئس مثوى المتكبرين","ފަހެ، އެތާނގައި ދެމިތިބެނިވި ގޮތުގައި، ތިޔަބައިމީހުން ނަރަކައިގެ ދޮރުތަކުން ވަންނާށެވެ! ފަހެ (އެއީ) ކިބުރުވެރިވެގެންވާ މީހުން ތިބުމަށް ހާދަހާ ނުބައިވެގެންވާ ތަނެކެވެ!","",""],["","","","وقيل للذين اتقوا ماذا أنزل ربكم قالوا خيرا للذين أحسنوا في هذه الدنيا حسنة ولدار الآخرة خير ولنعم دار المتقين","ތަގުވާވެރިވި މީހުންނަށް އަންގަވާނެތެވެ. ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ބާވައިލެއްވީ ކޮންއެއްޗެއް ހެއްޔެވެ؟ އެއުރެން ދަންނަވާނެތެވެ. ހެޔޮގޮތެވެ. މި ދުނިޔޭގައި ހެޔޮކޮށް ކަންތައްކުޅަ މީހުންނަށް ހެޔޮ ދަރުމަ ހުށްޓެވެ. އަދި އާޚިރަތްގެ ގޮވަތި، ހެޔޮކަން ބޮޑުކަން ކަށަވަރެވެ. އަދި ތަގުވާވެރިންގެ ގޮވަތީގެ މޮޅުކަމާއެވެ!","",""],["","","","جنات عدن يدخلونها تجري من تحتها الأنهار لهم فيها ما يشاءون كذلك يجزي الله المتقين","އެއީ ޢަދަނެވެ ކިއުނު ސުވަރުގެތަކެވެ. އެ ސުވަރުގެތަކަށް އެއުރެން ވަންނާނެތެވެ. އެތާނގެ ދަށުން ކޯރުތައް ހިނގަހިނގާ ހުރެތެވެ. އެއުރެން އެދޭކަންތައް، އެއުރެންނަށްޓަކައި އެތާނގައިވެއެވެ. ތަގުވާވެރިންނަށް ﷲ ޖަޒާ ދެއްވަނީ އެފަދައިންނެވެ.","",""],["","","","الذين تتوفاهم الملائكة طيبين يقولون سلام عليكم ادخلوا الجنة بما كنتم تعملون","އެއުރެންނަކީ، ކުށްފާފަތަކުން ތާހިރު ވެގެންވާ ޙާލު، މަލާއިކަތުން އެއުރެން މަރުގަންނަވާ މީހުންނެވެ. (އެ ހިނދު) އެ މަލާއިކަތުން ވިދާޅުވާނެތެވެ. ތިޔަބައިމީހުންގެ މައްޗަށް ސަލާމް ހުށްޓެވެ. ތިޔަބައިމީހުން ކޮށްއުޅުނު ޢަމަލުތަކުގެ ސަބަބުން، ތިޔަބައިމީހުން ސުވަރުގެއަށް ވަންނާށެވެ!","",""],["","","","هل ينظرون إلا أن تأتيهم الملائكة أو يأتي أمر ربك كذلك فعل الذين من قبلهم وما ظلمهم الله ولكن كانوا أنفسهم يظلمون","އެއުރެންގެ ގާތަށް މަލާއިކަތުން ވަޑައިގަތުމަށް، ނުވަތަ ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ (އަޒާބުގެ) އަމުރުފުޅު އައުމަށް މެނުވީ އެއުރެން އިންތިޒާރުކުރޭ ހެއްޔެވެ؟ އެއުރެންގެ ކުރީގެ މީހުންވެސް ކަންތައްކުޅައީ، ހަމައެފަދައިންނެވެ. ﷲ، އެއުރެންނަކަށް އަނިޔާއެއް ނުކުރައްވަތެވެ. އެހެނެއްކަމަކު، އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް، އެއުރެން އަނިޔާކުރާކަމުގައި ވޫއެވެ.","",""],["","","","فأصابهم سيئات ما عملوا وحاق بهم ما كانوا به يستهزئون","ފަހެ، އެއުރެން ޢަމަލުކުޅަގޮތުގެ ނުބައި ޖަޒާތައް، އެއުރެންނަށް ޖެހުނެވެ. އަދި އެއުރެން އެކަމަކަށް މަލާމާތްކޮށް އުޅުނު ކަންތައް އައިސް އެއުރެން ވަށައިލިއެވެ.","",""],["","","","وقال الذين أشركوا لو شاء الله ما عبدنا من دونه من شيء نحن ولا آباؤنا ولا حرمنا من دونه من شيء كذلك فعل الذين من قبلهم فهل على الرسل إلا البلاغ المبين","ޝަރީކުކުޅަ މީހުން ބުނެފޫއެވެ. ﷲ އިރާދަކުރެއްވިނަމަ، އެކަލާނގެ ފިޔަވައި އެހެން އެއްވެސް އެއްޗަކަށް ތިމަންމެންވެސް، އަދި ތިމަންމެންގެ ކާބަފައިންވެސް އަޅުކަމެއް ނުކުޅައީހެވެ. އަދި އެކަލާނގެ އެންގެވުމަކާނުލައި އެއްވެސް އެއްޗެއް ތިމަންމެން ހަރާމް ކޮށެއް ނުހެދީމުހެވެ. އެއުރެންގެ ކުރީގެ މީހުންވެސް ކަންތައްކުޅައީ، ހަމައެފަދައިންނެވެ. ފަހެ، ބަޔާންވެގެންވާ އިއްވެވުން މެނުވީ، ރަސޫލުންގެ މައްޗަށް ވޭހެއްޔެވެ؟","",""],["","","","ولقد بعثنا في كل أمة رسولا أن اعبدوا الله واجتنبوا الطاغوت فمنهم من هدى الله ومنهم من حقت عليه الضلالة فسيروا في الأرض فانظروا كيف كان عاقبة المكذبين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކޮންމެ އުއްމަތަކަށްމެ ރަސޫލަކު ފޮނުއްވީމެވެ. އެއީ، ﷲއަށް އަޅުކަންކުރުމަށާއި، ބުދުތަކާ ދުރުހެލިވުމަށް އެންގެވުމަށެވެ. ފަހެ، ﷲ ތެދުމަގު ދެއްކެވި މީހުން، އެއުރެންގެ ތެރެއިންވެއެވެ. އަދި މަގުފުރެދުން އެބަޔެއްގެ މައްޗަށް ހައްގު ވެގެންވީ މީހުންވެސް އެއުރެންގެ ތެރެއިންވެއެވެ. ފަހެ، ތިޔަބައިމީހުން ބިމުގައި ދަތުރުފަތުރުކޮށް އުޅޭށެވެ. ފަހެ، ދޮގުކުޅަމީހުންގެ ނަތީޖާއޮތީ ކޮންފަދައަކުންކަން ތިޔަބައިމީހުން ދެކޭށެވެ!","",""],["","","","إن تحرص على هداهم فإن الله لا يهدي من يضل وما لهم من ناصرين","އެއުރެންނަށް ތެދުމަގު ލިބުމުގެ މައްޗަށް ކަލޭގެފާނު ޝޫގުވެރިވެ ވަޑައިގަތަސް، ފަހެ، ހަމަކަށަވަރުން، ﷲ، އެކަލާނގެ މަގުފުރައްދަވާ މީހަކަށް ތެދުމަގެއް ނުދައްކަވަތެވެ. އަދި އެއުރެންނަށް ނަސްރު ދޭނޭ އެއްވެސް ބަޔަކު ނުވެތެވެ.","",""],["","","","وأقسموا بالله جهد أيمانهم لا يبعث الله من يموت بلى وعدا عليه حقا ولكن أكثر الناس لا يعلمون","އެއުރެންނަށް ވެވުނުހާ ގަދައެއްކޮށް ﷲ ގަންދީ ހުވާކޮށް އެއުރެން ބުނެފޫއެވެ. މަރުވާ މީހަކު (އަލުން އެހެން ދިރުމަކަށް) ﷲ ނުފޮނުއްވާނެތެވެ. އެހެންނަކުން ނޫނެވެ. (އެއީ) އެކަލާނގެއަށް ކަށަވަރުވެ ހައްގު ވެގެންވާ ގޮތުގައި، ކުރައްވާފައިވާ ވައުދެކެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުން (އެކަމެއް) ނުދަނެތެވެ.","",""],["","","","ليبين لهم الذي يختلفون فيه وليعلم الذين كفروا أنهم كانوا كاذبين","އެއުރެން އެކަމާމެދު ޚިލާފުވެ އުޅުނު ކަންތަކުގެ ހަގީގަތެއުރެންނަށް ބަޔާންކޮށްދެއްވުމަށްޓަކައެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެންވީ، ދޮގުވެރިންކަމުގައިކަން، ކާފިރުވި މީހުން ދެނެގަތުމަށްޓަކައެވެ.","",""],["","","","إنما قولنا لشيء إذا أردناه أن نقول له كن فيكون","ތިމަންރަސްކަލާނގެ ކަމަކަށް އިރާދަކުރައްވައިފި ހިނދަކު، ތިމަންރަސްކަލާނގެ އެކަމަކަށް އަންގަވާ ބަސްފުޅެއްކަމުގައިވާކަން ކަށަވަރީ، [ވާށޭ] ތިމަންރަސްކަލާނގެ އެކަމަކަށް ވަހީކުރެއްވުމެވެ. ދެން އެކަމެއް ވެދެތެވެ.","",""],["","","","والذين هاجروا في الله من بعد ما ظلموا لنبوئنهم في الدنيا حسنة ولأجر الآخرة أكبر لو كانوا يعلمون","އެއުރެންނަށް އަނިޔާ ލިބުމަށްފަހު، ﷲއަށްޓަކައި ހިޖުރަކުޅަ މީހުންނަށް، ހަމަކަށަވަރުން، ދުނިޔޭގައިވެސް އެއުރެން އުޅޭނޭ ރަނގަޅު ވަޒަން، ތިމަންރަސްކަލާނގެ ދެއްވާހުށީމެވެ. އަދި ހަމަކަށަވަރުން، އާޚިރަތްގެ ދަރުމަ މާބޮޑެވެ. އެއުރެން (އެކަން) ދަންނަނަމައެވެ.","",""],["","","","الذين صبروا وعلى ربهم يتوكلون","އެއުރެންނީ، ކެތްތެރިވި މީހުންނެވެ. އަދި އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ވަކީލުކުރާ މީހުންނެވެ.","",""],["","","","وما أرسلنا من قبلك إلا رجالا نوحي إليهم فاسألوا أهل الذكر إن كنتم لا تعلمون","އަދި ކަލޭގެފާނުގެ ކުރިންވެސް އެބަޔަކަށް ތިމަންރަސްކަލާނގެ ވަހީ އިއްވަވައި، ރަސޫލުކަމާއިގެން ފިރިހެނުން މެނުވީ، ނުފޮނުއްވަމެވެ. ފަހެ، ތިޔަބައިމީހުން ނުދަންނަ ކަމުގައި ވާނަމަ، ތިޔަބައިމީހުން އިލްމުގެ އަހުލުވެރިންނާ ސުވާލުކުރާށެވެ!","",""],["","","","بالبينات والزبر وأنزلنا إليك الذكر لتبين للناس ما نزل إليهم ولعلهم يتفكرون","(ތިމަންރަސްކަލާނގެ އެ ރަސޫލުން ފޮނުއްވީ) ބަޔާންވެގެންވާ ހެކިތަކާއި، ފޮތްތަކާއިގެންނެވެ. އަދި ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނަށް ގުރްއާން ބާވައިލެއްވީ، އެއުރެންނަށް ބާވައިލެއްވި ތަކެތި، މީސްތަކުންނަށް ކަލޭގެފާނު ބަޔާންކޮށް ދެއްވުމަށްޓަކައެވެ. އަދި އެއުރެން ފިކުރުކުރުމަށްޓަކައެވެ.","",""],["","","","أفأمن الذين مكروا السيئات أن يخسف الله بهم الأرض أو يأتيهم العذاب من حيث لا يشعرون","ފަހެ، ނުބައި ރޭވުންތައް ރޭވިމީހުން، ﷲއެއުރެންނާއިގެން ބިންގަނޑު ގަންބަވައިގެންފާނެ ކަމާމެދު، ނުވަތަ އެއުރެން ހީވެސްނުކުރާ ދިމަދިމާއިން، އެއުރެންނަށް އަޒާބު އަތުވެދާނެ ކަމާމެދު، އަމާންވެގެންވާ ކަމުގައި ހީކުޅައީ ހެއްޔެވެ؟","",""],["","","","أو يأخذهم في تقلبهم فما هم بمعجزين","ނުވަތަ އެއުރެން ދަތުރުފަތުރުކޮށް އުޅޭ އުޅުމުގެ ތެރޭގައި، އެކަލާނގެ އެއުރެން ހަލާކު ކުރައްވައިފާނެކަމާމެދުގައިވެސް މެއެވެ. ފަހެ، (ﷲ) ނުކުޅައްދައި، ރެކިގެން ދެވޭނޭ ބަޔަކު ކަމުގައި އެއުރެން ނުވެތެވެ.","",""],["","","","أو يأخذهم على تخوف فإن ربكم لرءوف رحيم","ނުވަތަ، އުނިކުރެއްވުމުގެގޮތުން (އެބަހީ: މުދަލާއި މީހުން މަދުވަމުންގޮސް މުޅިން ނެތިދާގޮތުން) އެއުރެން ހަލާކުކުރައްވައިފާނޭ ކަމާމެދުގައިވެސް މެއެވެ. ފަހެ، ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއީ، ނުހަނު އޯގާވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","أولم يروا إلى ما خلق الله من شيء يتفيأ ظلاله عن اليمين والشمائل سجدا لله وهم داخرون","އަދި ﷲ ހައްދަވާފައިވާ ތަކެއްޗަށް، އެއުރެން ނުބަލަނީ ހެއްޔެވެ؟ އެ ތަކެތީގެ ހިޔަނިތައް، ކަނާތްކިބައަށާއި، ވާތްކިބައަށް ލެނބިލެނބި ހުރެތެވެ. ﷲއަށް ސަޖިދަކުރާ ޙާލު ގައެވެ. އަދި އެ ހުރިހާ ތަކެތި، އެކަލާނގެއަށް ދެރަވެ، ނިކަމެތިވާ ޙާލު ގައެވެ.","",""],["","","","ولله يسجد ما في السماوات وما في الأرض من دابة والملائكة وهم لا يستكبرون","އުޑުތަކުގައިވާހާ ތަކެއްޗާއި، ބިމުގައި ހިނގާބިނގާއުޅޭ ދިރޭ ހުރިހާ ތަކެއްޗާއި، މަލާއިކަތުން، ﷲއަށް ސަޖިދަކުރެތެވެ. އަދި އެބޭކަލުން ބޮޑާވެއެއް ނުގަނެތެވެ.","",""],["","","","يخافون ربهم من فوقهم ويفعلون ما يؤمرون","އެބޭކަލުންގެ މައްޗަށް، މަތިވެރިވެވޮޑިގެންވާ، އެބޭކަލުންގެ ވެރިރަސްކަލާނގެއަށް، އެބޭކަލުން ބިރުވެތިވެތެވެ. އަދި އެބޭކަލުންނަށް އަމުރުކުރައްވާ ކަންތައް، އެބޭކަލުން ކުރައްވަތެވެ.","",""],["","","","وقال الله لا تتخذوا إلهين اثنين إنما هو إله واحد فإياي فارهبون","ﷲ ވަހީކުރެއްވިއެވެ. ތިޔަބައިމީހުން، ދެ އިލާހުން ވާކަމަށް ގަބޫލު ނުކުރާށެވެ! ހަމަކަށަވަރުން، އެކަލާނގެ ވާކަން ކަށަވަރީ، އެއްކައުވަންތަ ކަލާނގެ ކަމުގައެވެ. ފަހެ، ތިޔަބައިމީހުން ހަމައެކަނި، ތިމަންރަސްކަލާނގެއަށް ބިރުވެތިވާށެވެ!","",""],["","","","وله ما في السماوات والأرض وله الدين واصبا أفغير الله تتقون","އަދި އުޑުތަކާއި، ބިމުގައިވާހާ އެއްޗެއް މިލްކުވެގެންވަނީ، އެކަލާނގެއަށެވެ. އަދި އަބަދުގެ އަބަދަށް، ކިޔަމަންވުންވަނީވެސް އެކަލާނގެއަށެވެ. ފަހެ، ތިޔަބައިމީހުން ބިރުވެތިވަނީ، ﷲ ނޫން ފަރާތަކަށް ހެއްޔެވެ؟","",""],["","","","وما بكم من نعمة فمن الله ثم إذا مسكم الضر فإليه تجأرون","އަދި ތިޔަބައިމީހުންގެ ކިބައިގައިވާހާ ނިއުމަތެއް ވަނީ، ﷲގެ ހަޒުރަތުންނެވެ. ދެން ތިޔަބައިމީހުންނަށް ދަތިޙާލު ޖެހިއްޖެނަމަ، ފަހެ، ތިޔަބައިމީހުން ދުއާ ކޮށް ދަންނަވަނީ، ހަމަ އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","ثم إذا كشف الضر عنكم إذا فريق منكم بربهم يشركون","ދެން އެކަލާނގެ، ތިޔަބައިމީހުންގެ ކިބައިން، އެ ދަތިޙާލު ފިއްލަވައިފިނަމަ، އެހާރުން ތިޔަބައިމީހުންކުރެ ބަޔަކު، އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ޝަރީކުކުރެތެވެ.","",""],["","","","ليكفروا بما آتيناهم فتمتعوا فسوف تعلمون","އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ދެއްވި ނިއުމަތަށް، ކާފިރު ވުމަށްޓަކައެވެ. ފަހެ، ތިޔަބައިމީހުން (ދުނިޔޭގައި ވަގުތުކޮޅަކަށް) އަރާމު ލިބިގަންނާށެވެ! ފަހެ، ނިކަންހުރެ ތިޔަބައިމީހުންނަށް (އޭގެ ނަތީޖާ) އެނގޭހުށްޓެވެ.","",""],["","","","ويجعلون لما لا يعلمون نصيبا مما رزقناهم تالله لتسألن عما كنتم تفترون","ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްވި ތަކެތިން ބައެއް، އެއުރެންނަށް އެނގުމެއްނުވާ ތަކެއްޗަށް (އެބަހީ: ބުދުތަކަށް) ދީއުޅެތެވެ. ﷲ ގަންދެއްވައި ވަހީކުރައްވަމެވެ. ތިޔަބައިމީހުން، ހަދައިއުޅުނު ދޮގުތަކާމެދު، ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނާ ސުވާލުކުރައްވާ ހުށްޓެވެ.","",""],["","","","ويجعلون لله البنات سبحانه ولهم ما يشتهون","އަދި ﷲއަށް އަންހެންދަރިން ވާކަމަށް، އެއުރެން ހަދަތެވެ. އެކަލާނގެ (އެފަދަ ކަންކަމުން) ހުސްތާހިރު ވެވޮޑިގެންވެއެވެ. އަދި އެއުރެން އެދޭ ތަކެތި، (އެބަހީ: ފިރިހެންދަރިން) ވަނީ، އެއުރެންނަށްކަމަށް ހަދަތެވެ.","",""],["","","","وإذا بشر أحدهم بالأنثى ظل وجهه مسودا وهو كظيم","އަދި އެއިން މީހަކަށް، އަންހެންދަރިއެއް ލިބިއްޖެކަމުގެ ޚަބަރު ދެވިއްޖެނަމަ، އެމީހެއްގެ މޫނު އަނދިރިވެގެންދެތެވެ. އޭނާއަށް އެކަމުގެ ހިތާމަ ލިބިގެންވާ ޙާލު ގައެވެ.","",""],["","","","يتوارى من القوم من سوء ما بشر به أيمسكه على هون أم يدسه في التراب ألا ساء ما يحكمون","އެމީހާއަށް ދެވުނު ޚަބަރުގެ ނުބައިކަމުން، މީސްތަކުންގެ ކިބައިން އޭނާ ނިވައިވެގަނެތެވެ. ނިކަމެތިކަންމަތީގައި، އޭނާ އެ ކުއްޖާ ގެންގުޅޭނީ ބާވައެވެ؟ ނުވަތަ ފަސްގަނޑުގެ ތެރެޔަށް އެ ކުއްޖާ ކޮށްޕައިލާނީ ބާވައެވެ؟ ދަންނާށެވެ! އެއުރެންކުރާ ހުކުމް ހާދަހާ ނުބައިވެގެންވެއެވެ.","",""],["","","","للذين لا يؤمنون بالآخرة مثل السوء ولله المثل الأعلى وهو العزيز الحكيم","ނުބައިވެގެންވާ މިސާލު ވަނީ، އާޚިރަތަށް އީމާން ނުވާ މީހުންނަށެވެ. އަދި އެންމެ މަތިވެރި މިސާލު ވަނީ، ﷲއަށެވެ. އަދި އެކަލާނގެއީ، ޢަޒީޒުވަންތަ ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ولو يؤاخذ الله الناس بظلمهم ما ترك عليها من دابة ولكن يؤخرهم إلى أجل مسمى فإذا جاء أجلهم لا يستأخرون ساعة ولا يستقدمون","އަދި އެއުރެންގެ އަނިޔާގެ ސަބަބުން ﷲ މީސްތަކުންނަށް (ވަގުތުން) އުގޫބާތް ދެއްވާނަމަ، ހިނގާބިނގާ އުޅޭ އެއްވެސް ދިރޭއެއްޗެއް، އެ ބިންމަތީގައި (އުޅުމަށް) ދޫނުކުރެއްވީހެވެ. އެހެނެއްކަމަކު، ކަނޑައެޅިގެންވާ މުއްދަތަކަށް، އެކަލާނގެ އެއުރެން ފަސްކުރައްވަނީއެވެ. ފަހެ، އެއުރެންގެ އަޖަލު އައުމުން، އެންމެ ހިނދުކޮޅަކަށްވެސް އެއުރެންނަކަށް، ލަހެއް ނުކުރައްވާހުށްޓެވެ. އަދި އަވަހެއްވެސް ނުމެކުރައްވާ ހުށްޓެވެ.","",""],["","","","ويجعلون لله ما يكرهون وتصف ألسنتهم الكذب أن لهم الحسنى لا جرم أن لهم النار وأنهم مفرطون","އަދި އެއުރެން، ނުރުހޭ ތަކެތި (އެބަހީ: އަންހެންދަރިން) އެއުރެން ﷲއަށް ނިސްބަތްކުރެތެވެ. އަދި ހަމަކަށަވަރުން، ހުރިހާ ހެވެއްވަނީ، އެއުރެންނަށް ކަމަށްބުނެ، އެއުރެންގެ ދޫތަކުން ދޮގުތައް ހަދައި އުޅެތެވެ. ޝައްކެއް ނެތެވެ. ހަމަކަށަވަރުން، އެއުރެންނަށްހުރީ ނަރަކައެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެންނީ، އެންމެ ފުރަތަމަ އެ ތަނަށް ދޫކުރައްވާނޭ ބަޔެކެވެ.","",""],["","","","تالله لقد أرسلنا إلى أمم من قبلك فزين لهم الشيطان أعمالهم فهو وليهم اليوم ولهم عذاب أليم","ﷲ ގަންދެއްވައި ވަހީކުރައްވަމެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ކުރީގެ އުއްމަތްތަކަށް، ތިމަންރަސްކަލާނގެ ރަސޫލުން ފޮނުއްވީމެވެ. ދެން ޝައިތާނާ، އެއުރެންނަށް އެއުރެންގެ ޢަމަލުތައް ޒީނަތްތެރިކޮށް ދެއްކިއެވެ. ފަހެ، މިއަދު އެއުރެންގެ އެހީތެރިޔަކީ، އެ ޝައިތާނާއެވެ. އަދި އެއުރެންނަށް، ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["","","","وما أنزلنا عليك الكتاب إلا لتبين لهم الذي اختلفوا فيه وهدى ورحمة لقوم يؤمنون","އަދި އެއުރެން އެކަމާމެދު ޚިލާފު ވީ ކަންތައް، ކަލޭގެފާނު އެއުރެންނަށް ބަޔާންކޮށްދެއްވުމަށްޓަކައި މެނުވީ، އަދި އީމާންވާ ބަޔަކަށް ތެދުމަގެއް ކަމުގައްޔާއި، ރަހުމަތެއް ކަމުގައި މެނުވީ، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް، ފޮތް ބާވައެއް ނުލައްވަމެވެ.","",""],["","","","والله أنزل من السماء ماء فأحيا به الأرض بعد موتها إن في ذلك لآية لقوم يسمعون","ﷲ، އުޑުން ފެން ބާވައިލެއްވިއެވެ. ފަހެ، ބިންގަނޑު މަރުވެ އޮތުމަށްފަހު، އެ ފެނުގެ ސަބަބުން، އެކަލާނގެ އެ ބިންގަނޑު ދިރުއްވިއެވެ. ހަމަކަށަވަރުން، އަޑުއަހާ ބަޔަކަށް، އެކަމުގައި ހެތްކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","وإن لكم في الأنعام لعبرة نسقيكم مما في بطونه من بين فرث ودم لبنا خالصا سائغا للشاربين","އަދި ހަމަކަށަވަރުން، ނަޢަމް ސޫފީގައި، ތިޔަބައިމީހުންނަށް އިބްރަތެއް ވާކަން ކަށަވަރެވެ. އޭގެ ބަނޑުގައިވާ ތަކެތިން، ތިޔަބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ ބުއިމެއް ދެއްވަމެވެ. (ބަނޑުތެރޭގައިވާ) ފުޟޫލާތު ތަކާއި، ލެޔާ ދެމެދުން އުފެދިގެން އަންނަ ބުއިމެކެވެ. ބޯމީހުންނަށް ބުއިމަށް ފަސޭހަ، އަދި ސާފުވެގެންވާ ކިރެވެ.","",""],["","","","ومن ثمرات النخيل والأعناب تتخذون منه سكرا ورزقا حسنا إن في ذلك لآية لقوم يعقلون","އަދި ކަދުރު ރުކުގެ މޭވާއާއި، މޭބިސްކަދުރުން މަސްތުވާ ބުއިންތަކާއި، ރަނގަޅު ކާތަކެތި ތިޔަބައިމީހުން ބޭނުންކުރަމުއެވެ. ހަމަކަށަވަރުން، ވިސްނާބަޔަކަށް، އެކަމުގައި ހެތްކެއްވާކަން ކަށަވަރެވެ. (ނޯޓު: މި އާޔަތް ބާވައިލެއްވީ، ރާ ހަރާމްކުރެއްވުމުގެ ކުރީގައެވެ.)","",""],["","","","وأوحى ربك إلى النحل أن اتخذي من الجبال بيوتا ومن الشجر ومما يعرشون","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ކުޅަނދުރަށް އިލްހާމްކުރައްވައި އެންގެވިއެވެ. ފަރުބަދަތަކުގައްޔާއި، ގަސްގަހާގެހީގައްޔާއި، މީހުން ހަދައިދޭ ބިނާތަކުގައި، ހަތާހަދައި އުޅޭށެވެ!","",""],["","","","ثم كلي من كل الثمرات فاسلكي سبل ربك ذللا يخرج من بطونها شراب مختلف ألوانه فيه شفاء للناس إن في ذلك لآية لقوم يتفكرون","ދެން ތިޔަ ކުޅަނދުރު، ހުރިހާ މޭވާތަކުން ކައިއުޅޭށެވެ! ފަހެ، ތިޔަ ކުޅަނދުރުގެ ވެރިރަސްކަލާނގެ، ފަސޭހަކޮށް ދެއްވާފައިވާ މަގުތަކުން ހިނގާށެވެ! އެ ތަކެތީގެ ބަނޑުން ކުލަތައް ތަފާތު ބުއިމެއް ނުކުމެގެން އާދެތެވެ. އޭގައި (އެބަހީ: މާމުއިގައި) މީސްތަކުންނަށް ބަލިފަސޭހަވުން ވެއެވެ. ހަމަކަށަވަރުން، ފިކުރުކުރާ ބަޔަކަށް، އެކަމުގައި ހެތްކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","والله خلقكم ثم يتوفاكم ومنكم من يرد إلى أرذل العمر لكي لا يعلم بعد علم شيئا إن الله عليم قدير","ﷲ، ތިޔަބައިމީހުން ހެއްދެވިއެވެ. ދެން އެކަލާނގެ، ތިޔަބައިމީހުން މަރުގަންނަވަތެވެ. އަދި އެންމެ ނިކަމެތި އުމުރަށް ރައްދުކުރައްވާ މީހުން، ތިޔަބައިމީހުންގެ ތެރެއިންވެއެވެ. އެއީ އެމީހާއަށް އެނގިގެންވުމަށްފަހު، އެއްވެސް އެއްޗެއް ނޭނގުމަށްޓަކައެވެ. ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","والله فضل بعضكم على بعض في الرزق فما الذين فضلوا برادي رزقهم على ما ملكت أيمانهم فهم فيه سواء أفبنعمة الله يجحدون","އަދި ﷲ، ރިޒްގު ދެއްވުމުގައި، ތިޔަބައިމީހުންގެ އެއްބަޔަކު އަނެއްބަޔަކުގެ މައްޗަށް މާތްކުރައްވައި، އިތުރުކުރެއްވިއެވެ. ފަހެ، އެއުރެންނަށް މިލްކުވެގެންވާ އަޅުންނަށް، އެއުރެންގެ ރިޒްގު ރައްދުކޮށްދޭ ބަޔަކުކަމުގައި، އިތުރު ކުރެއްވި މީހުން ނުވެތެވެ. ފަހެ، އެކަމުގައި، އެއުރެން ހަމަހަމަވެގެންވެއެވެ. ފަހެ، އެއުރެން އިންކާރު ކޮށް ދެކޮޅުހަދަނީ، ﷲ ދެއްވި ނިއުމަތާ މެދުގައި ހެއްޔެވެ؟","",""],["","","","والله جعل لكم من أنفسكم أزواجا وجعل لكم من أزواجكم بنين وحفدة ورزقكم من الطيبات أفبالباطل يؤمنون وبنعمت الله هم يكفرون","އަދި ﷲ، ތިޔަބައިމީހުންގެ ތެރެއިން، ތިޔަބައިމީހުންނަށްޓަކައި، އަނބިންލައްވައި، އަދި ތިޔަބައިމީހުންގެ އަނބިންގެ ކިބައިން، ދަރިންނާއި، ދަރިންގެދަރިން ލައްވައި، އަދި ރަނގަޅު ހަލާލު ތަކެތިން، ތިޔަބައިމީހުންނަށް ރިޒްގު ދެއްވިއެވެ. ފަހެ، އެއުރެން އީމާން ވަނީ، ބާތިލަށް ހެއްޔެވެ؟ އަދި އެއުރެން ކާފިރު ވަނީ، ﷲގެ ނިއުމަތަށް ހެއްޔެވެ؟","",""],["","","","ويعبدون من دون الله ما لا يملك لهم رزقا من السماوات والأرض شيئا ولا يستطيعون","ﷲ ފިޔަވައި، އެހެންފަރާތަކަށް، އެއުރެން އަޅުކަންކުރެތެވެ. (އެއީ) އުޑުތަކާއި، ބިމުން، އެއްވެސް އެއްޗަކުން އެއުރެންނަށް ރިޒްގު ދިނުން މިލްކުވެގެން ނުވާ ތަކެއްޗެވެ. އަދި އެ ތަކެއްޗަށް، އެކަމަކަށް ކުޅަދާނަވެގެނެއް ނުމެވޭމެއެވެ.","",""],["","","","فلا تضربوا لله الأمثال إن الله يعلم وأنتم لا تعلمون","ފަހެ، ތިޔަބައިމީހުން، އެއްވެސް އެއްޗެއް ﷲއާ އެއްފަދަ ނުކުރާށެވެ! ހަމަކަށަވަރުން، ﷲ ދެނެވޮޑިގެންވެތެވެ. އަދި ތިޔަބައިމީހުންނަކަށް ނޭނގެތެވެ.","",""],["","","","ضرب الله مثلا عبدا مملوكا لا يقدر على شيء ومن رزقناه منا رزقا حسنا فهو ينفق منه سرا وجهرا هل يستوون الحمد لله بل أكثرهم لا يعلمون","އެހެންމީހަކަށް މިލްކުވެގެންވާ، އަދި އެއްވެސްކަމެއް ކުރުމަށް ކުޅަދާނަވެގެންނުވާ އަޅަކާއި، ތިމަންރަސްކަލާނގެ ހެޔޮވެގެންވާ ރިޒްގުން ރިޒްގު ދެއްވައި، ސިއްރާއި ފާޅުގައި އެއިން ހޭދަކޮށްއުޅޭ މީހަކާ ދެމީހުންގެ މިސާލުން ﷲ، މިސާލެއް ޖެއްސެވިއެވެ. އެއުރެން ހަމަހަމަވާނޭ ހެއްޔެވެ؟ ހަމްދު ހުރީ، ﷲއަށެވެ. އަދި ކިއެއްތަ! އެއުރެންކުރެ ގިނަ މީހުންނަކަށް ނޭނގެތެވެ.","",""],["","","","وضرب الله مثلا رجلين أحدهما أبكم لا يقدر على شيء وهو كل على مولاه أينما يوجهه لا يأت بخير هل يستوي هو ومن يأمر بالعدل وهو على صراط مستقيم","ދެފިރިހެނެއްގެ މިސާލުން، ﷲ މިސާލެއް ޖެއްސެވިއެވެ. އެ ދެމީހުންކުރެ އެކަކީ، އެއްވެސްކަމެއްގެ މައްޗަށް ކުޅަދާނަވެގެންނުވާ މަންމަނެކެވެ. އަދި އޭނާއަކީ، އޭނާގެ ސާހިބުމީހާގެ މައްޗަށްވާ ބުރައެކެވެ. އޭނާ ކުރިމަތިކޮށްފި އެއްވެސް ދިމާއަކުން، ހެޔޮކަމަކާއިގެނެއް ނާދެތެވެ. އެމީހާއާއި، ސީދާވެގެންވާ ތެދުމަގުގައިހުރެ، އިންޞާފަށް އަމުރުކޮށްއުޅޭ މީހަކާ ހަމަހަމަވެގެންވާނޭ ހެއްޔެވެ؟","",""],["","","","ولله غيب السماوات والأرض وما أمر الساعة إلا كلمح البصر أو هو أقرب إن الله على كل شيء قدير","އަދި އުޑުތަކާއި، ބިމުގެ ޣައިބު މިލްކުވެގެންވަނީ، ﷲއަށެވެ. އަދި ގިޔާމަތް ވުމުގެ ވަގުތުގެ ކަންތައް، ލޮލުގެ އެސްފިޔަޖަހާހައި ހިނދުކޮޅެއް ފަދައިން މެނުވީ ނުވެތެވެ. ނުވަތަ، އެއަށްވުރެވެސް ގާތެވެ. ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","والله أخرجكم من بطون أمهاتكم لا تعلمون شيئا وجعل لكم السمع والأبصار والأفئدة لعلكم تشكرون","ތިޔަބައިމީހުންނަށް އެއްވެސް އެއްޗެއް ނޭނގޭގޮތުގައިވާ ޙާލު، ތިޔަބައިމީހުންގެ މައިންގެ ބަނޑުން، ތިޔަބައިމީހުން ނެރުއްވީ ﷲއެވެ. އަދި އެކަލާނގެ ތިޔަބައިމީހުންނަށް އިވުމާއި، ފެނުމާއި، ހިތްތައް ލެއްވިއެވެ. އެއީ ތިޔަބައިމީހުން، ޝުކުރުކުރުމަށްޓަކައެވެ.","",""],["","","","ألم يروا إلى الطير مسخرات في جو السماء ما يمسكهن إلا الله إن في ذلك لآيات لقوم يؤمنون","އުޑުގެ ޖައްވުގައި ކިޔަމަންކުރައްވާފައިވާ ދޫނިތައް، އެއުރެން ނުދެކެނީ ހެއްޔެވެ؟ އެތަކެތި (އުދުހޭ ގޮތުގައި) ﷲ މެނުވީ ނުހިފަހައްޓަވަތެވެ. އީމާންވާ ބަޔަކަށް، ހަމަކަށަވަރުން، އެކަމުގައި ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","والله جعل لكم من بيوتكم سكنا وجعل لكم من جلود الأنعام بيوتا تستخفونها يوم ظعنكم ويوم إقامتكم ومن أصوافها وأوبارها وأشعارها أثاثا ومتاعا إلى حين","އަދި ﷲ، ތިޔަބައިމީހުން ހިމޭންވެތިބޭ ތަންތަންކަމުގައި، ތިޔަބައިމީހުންނަށް، ތިޔަބައިމީހުންގެ ގެތައް ލެއްވިއެވެ. އަދި ތިޔަބައިމީހުންގެ ދަތުރުގެ ދުވަހުގައްޔާއި، ދަތުރުނުކޮށް ގާއިމު ވެތިބޭ ދުވަހުގައި، ގެންގުޅުމަށް ލުއި ގެތަކެއް، ނަޢަމް ސޫފީގެ ހަމުން ތިޔަބައިމީހުންނަށްޓަކައި ލެއްވިއެވެ. އަދި އެ ތަކެތީގެ ކެހެރިންނާއި، އެ ތަކެތީގެ ލޯލިންނާއި، އެ ތަކެތީގެ އިސްތަށިން، ގެވެހި ސާމާނާއި، ހިފައިގެންގުޅޭ ތަކެތި، ތިޔަބައިމީހުންނަށްޓަކައި، ވަކި މުއްދަތަކަށް ލެއްވިއެވެ.","",""],["","","","والله جعل لكم مما خلق ظلالا وجعل لكم من الجبال أكنانا وجعل لكم سرابيل تقيكم الحر وسرابيل تقيكم بأسكم كذلك يتم نعمته عليكم لعلكم تسلمون","އަދި ﷲ، އެކަލާނގެ ހެއްދެވި ތަކެތިން، ހިޔާތައް ތިޔަބައިމީހުންނަށްޓަކައި ލެއްވިއެވެ. އަދި ތިޔަބައިމީހުން، ރައްކާތެރިކަން ލިބިގަތުމަށް، ވަދެތިބޭނޭ ތަންތަން، ފަރުބަދަތަކުން، ތިޔަބައިމީހުންނަށްޓަކައި ލެއްވިއެވެ. އަދި (ފިނި) ހޫނުކަމުން، ތިޔަބައިމީހުން ރައްކާތެރިކޮށްދޭ ފޭރާންތަކާއި، ހަނގުރާމައިގެ ނުރައްކާތެރިކަމުން، ތިޔަބައިމީހުން ރައްކާތެރިކޮށްދޭ ފޭރާންތައް، ތިޔަބައިމީހުންނަށްޓަކައި، އެކަލާނގެ ލެއްވިއެވެ. ތިޔަބައިމީހުންގެ މައްޗަށް، އެކަލާނގެ ނިއުމަތް ފުރިހަމަކޮށްދެއްވަނީ، އެފަދައިންނެވެ. އެއީ، ތިޔަބައިމީހުން ކިޔަމަންވުމަށްޓަކައެވެ.","",""],["","","","فإن تولوا فإنما عليك البلاغ المبين","ފަހެ، އެއުރެން ފުރަގަސްދީފިނަމަ، ފަހެ، ކަލޭގެފާނުގެ މައްޗަށް އޮތްކަން ކަށަވަރީ، ބަޔާންވެގެންވާ އިއްވެވުމެވެ.","",""],["","","","يعرفون نعمت الله ثم ينكرونها وأكثرهم الكافرون","އެއުރެން ﷲގެ ނިއުމަތް ދަނެތެވެ. ދެން އެއުރެން އެއަށް އިންކާރުކުރެތެވެ. އަދި އެއުރެންކުރެ ގިނަމީހުންނީ، ކާފިރުންނެވެ.","",""],["","","","ويوم نبعث من كل أمة شهيدا ثم لا يؤذن للذين كفروا ولا هم يستعتبون","ތިމަންރަސްކަލާނގެ ކޮންމެ އުއްމަތަކުން، ހެކިވެރިޔަކު ފޮނުއްވަވާ ދުވަސް ހަނދުމަކުރާށެވެ! ދެން ކާފިރު ވިމީހުންނަށް (އުޒުރު ދެއްކުމަކަށް) އިޛުނެއް ނުދެއްވާހުށްޓެވެ. އަދި އެކަލާނގެ ރުއްސަވާ މަގަށް، އެނބުރި އާދެވޭނޭ ބަޔަކު ކަމުގައި، އެއުރެން އެދުވަހުން ނުވެތެވެ.","",""],["","","","وإذا رأى الذين ظلموا العذاب فلا يخفف عنهم ولا هم ينظرون","އަދި އަނިޔާވެރިވި މީހުން، އަޒާބު ދެކޭހިނދު، އެއުރެންގެ ކިބައިން އެކަން ލުއި ނުކުރައްވާހުށްޓެވެ. އަދި ފަސްކުރައްވާނޭ ބަޔަކުކަމުގައިވެސް، އެއުރެން ނުމެވޭމެއެވެ.","",""],["","","","وإذا رأى الذين أشركوا شركاءهم قالوا ربنا هؤلاء شركاؤنا الذين كنا ندعو من دونك فألقوا إليهم القول إنكم لكاذبون","އަދި ޝަރީކުކުޅަ މީހުން، އެއުރެން (ﷲއާ) ޝަރީކުކުޅަ ފަރާތްތައް ދެކޭހިނދު ބުނާނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! މިތިބީ އަޅަމެންގެ ޝަރީކުންނެވެ. އެއީ، އިބަރަސްކަލާނގެ ފިޔަވައި، އަޅަމެން އެފަރާތްތަކަށް އަޅުކަންކޮށް އުޅުނު ފަރާތްތަކެވެ. ދެން ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނީ، ދޮގުވެރިންނޭ ބުނެ، އެ ތަކެތި އެއުރެންނަށް އެބަސް ރައްދުކުރާނެތެވެ.","",""],["","","","وألقوا إلى الله يومئذ السلم وضل عنهم ما كانوا يفترون","އަދި އެއުރެން އެދުވަހުން، ﷲއަށް ތަސްލީމްކުރާނެތެވެ. އަދި އެއުރެން އަމިއްލަޔަށް ހަދައިގެން އުޅުނު ބާތިލު އިލާހު ންތައް، އެއުރެންނަށް ގެއްލިގެންދާނެތެވެ.","",""],["","","","الذين كفروا وصدوا عن سبيل الله زدناهم عذابا فوق العذاب بما كانوا يفسدون","(ﷲއަށާއި އެކަލާނގެ ރަސޫލާއަށް) ކާފިރުވެ، އަދި ﷲގެ މަގުން (އެހެން މީހުން) އެއްކިބާކުރި މީހުންނަށް، އަޒާބުގެ މައްޗަށް އަޒާބު ތިމަންރަސްކަލާނގެ އިތުރުކުރައްވާ ހުށީމެވެ. އެއީ، އެއުރެން ފަސާދަކޮށް އުޅުނުކަމަށްޓަކައެވެ.","",""],["","","","ويوم نبعث في كل أمة شهيدا عليهم من أنفسهم وجئنا بك شهيدا على هؤلاء ونزلنا عليك الكتاب تبيانا لكل شيء وهدى ورحمة وبشرى للمسلمين","އަދި ތިމަންރަސްކަލާނގެ ކޮންމެ އުއްމަތަކުން ހެކިވެރިއަކު، ހަމަ އެއުރެންގެ ތެރެއިން އެއުރެންގެ މައްޗަށް ފޮނުއްވާ ދުވަސް ހަނދުމަކުރާށެވެ! އަދި މިބައިމީހުންގެ މައްޗަށް ހެކިވެރިޔަކު ކަމުގައި، ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނު ގެންނަވާ ހުށީމެވެ. އަދި ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނުގެ މައްޗަށް ފޮތް ބާވައިލެއްވީމެވެ. (އެއީ) ކޮންމެކަމެއް ބަޔާންކޮށްދެއްވާ ގޮތުގައެވެ. އަދި މުސްލިމުންނަށް އޮތް ހިދާޔަތެއް ކަމުގައްޔާއި، ރަހުމަތެއް ކަމުގައްޔާއި، އުފާވެރި ޚަބަރެއް ކަމުގައެވެ.","",""],["","","","إن الله يأمر بالعدل والإحسان وإيتاء ذي القربى وينهى عن الفحشاء والمنكر والبغي يعظكم لعلكم تذكرون","ހަމަކަށަވަރުން، ޢަދުލުވެރިވުމަށާއި، އިހްސާން ތެރިވުމަށާއި، ގާތްތިމާގެ މީހުންނަށް ހެޔޮފޯރުވުމަށް ﷲ އަމުރުކުރައްވަތެވެ. އަދި ހުތުރުކަން ބޮޑުވެގެންވާ ފާފަތަކާއި، މުންކަރާތް ތަކާއި، އަނިޔާވެރިވެ އުޅުން، އެކަލާނގެ ނަހީކުރައްވަތެވެ. އެކަލާނގެ، ތިޔަބައިމީހުންނަށް، ވައުޒު އިއްވަވަނީ، ތިޔަބައިމީހުން ހަނދުމަކުރުމަށްޓަކައެވެ.","",""],["","","","وأوفوا بعهد الله إذا عاهدتم ولا تنقضوا الأيمان بعد توكيدها وقد جعلتم الله عليكم كفيلا إن الله يعلم ما تفعلون","ތިޔަބައިމީހުން ﷲއަށް އަހުދު ކޮށްފިނަމަ، އެ އަހުދު ތިޔަބައިމީހުން ފުއްދާށެވެ! އަދި ހުވާތައް ގަދަކޮށް، ކަށަވަރުކުރުމަށްފަހު، ތިޔަބައިމީހުން އެ ހުވާތައް އުވައިނުލާށެވެ! އެހެނީ، ހަމަކަށަވަރުން، ﷲއީ، ތިޔަބައިމީހުންގެ މައްޗަށް، ހެކިވެ ޖާމިނުވެވޮޑިގެންވާ ފަރާތެއް ކަމުގައި، ތިޔަބައިމީހުން ލާފައިވެއެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ކުރާ ކަންތައް، ﷲ ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","ولا تكونوا كالتي نقضت غزلها من بعد قوة أنكاثا تتخذون أيمانكم دخلا بينكم أن تكون أمة هي أربى من أمة إنما يبلوكم الله به وليبينن لكم يوم القيامة ما كنتم فيه تختلفون","އަދި އުއިގުޅައި، ރޮދިއަޅައި ހަރުކުރުމަށްފަހު، އެތިއެތިކޮޅަށް އެ ކޮށައި ހަލާކުކޮށްލި ކަނބުލޭގެ ފަދައިން، ތިޔަބައިމީހުން ނުވާށެވެ! (އެބަހީ: އަހުދުތަކުގެ ބާރު ލިބިގަތުމަށްފަހު، އެ އަހުދުތައް އުވައިލާ ބަޔަކު ކަމުގައި ތިޔަބައިމީހުން ނުވާށެވެ!) ތިޔަބައިމީހުންގެ މެދުގައި، ފަސާދަވެރިކަން އުފެއްދުމަށްޓަކައި އޮތް އެއްޗެއްކަމުގައި، ތިޔަބައިމީހުންގެ ހުވާތައް ހަދަމުއެވެ. (އެއީ) ތިޔަބައިމީހުންކުރެ އެއްބަޔަކު، އަނެއްބަޔަކަށްވުރެ ގިނަބަޔަކުކަމުގައި ވެދާނެތީއެވެ. ހަމަކަށަވަރުން، ﷲ، ތިޔަބައިމީހުން އެކަމުން އިމްތިހާނުކުރައްވަތެވެ. އަދި ތިޔަބައިމީހުން، ޚިލާފުވެ އުޅުނުކަންތައް، ގިޔާމަތް ދުވަހުން އެކަލާނގެ ތިޔަބައިމީހުންނަށް ބަޔާންކޮށްދެއްވާނެކަން ކަށަވަރެވެ.","",""],["","","","ولو شاء الله لجعلكم أمة واحدة ولكن يضل من يشاء ويهدي من يشاء ولتسألن عما كنتم تعملون","ﷲ އިރާދަކުރެއްވިނަމަ، އެއް އުއްމަތެއް ކަމުގައި، ތިޔަބައިމީހުން ލައްވައިފީސްކަން ކަށަވަރެވެ. އެހެނެއްކަމަކު، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކު މަގުފުރައްދަވަތެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ތެދުމަގު ދައްކަވަތެވެ. އަދި ތިޔަބައިމީހުން ޢަމަލު ކޮށް އުޅުނު ކަންތަކާމެދު، ތިޔަބައިމީހުންނާ ސުވާލުކުރައްވާހުށިކަން ކަށަވަރެވެ.","",""],["","","","ولا تتخذوا أيمانكم دخلا بينكم فتزل قدم بعد ثبوتها وتذوقوا السوء بما صددتم عن سبيل الله ولكم عذاب عظيم","ތިޔަބައިމީހުންގެ ހުވާތައް، އެއީ ތިޔަބައިމީހުންގެ މެދުގައި ފަސާދަ ކުރުމަށްޓަކައި އޮތް އެއްޗެއް ކަމުގައި ތިޔަބައިމީހުން ނަހަދާށެވެ! ފަހެ، (އެހެންވެއްޖެނަމަ، އެ ހުވާގެ ސަބަބުން) ފައިތިލަ ޘާބިތުވެ ހުރުމަށްފަހު، އެ ފައިތިލަ ކައްސާލައިގެން ހިނގައިދާނެތެވެ. އަދި ތިޔަބައިމީހުން، ﷲގެ މަގުން (މީސްތަކުން) އެއްކިބާކޮށްއުޅުމުގެ ސަބަބުން، މުސީބާތްގެ ރަހަ ތިޔަބައިމީހުންނަށް ލިބިދާނެތެވެ. އަދި ބޮޑުވެގެންވާ އަޒާބު، ތިޔަބައިމީހުންނަށް ހުށްޓެވެ.","",""],["","","","ولا تشتروا بعهد الله ثمنا قليلا إنما عند الله هو خير لكم إن كنتم تعلمون","އަދި ތިޔަބައިމީހުން، ﷲގެ އަހުދަށް ކުޑަ އަގެއް ނުގަންނާށެވެ! ތިޔަބައިމީހުން ދަންނަކަމުގައިވާނަމަ، ހަމަކަށަވަރުން، ﷲގެ ހަޒުރަތު ގައިވާ އެއްޗެއް އެއީ، ތިޔަބައިމީހުންނަށް އެންމެ ހެޔޮކަން ބޮޑުވެގެންވާ އެއްޗެކެވެ.","",""],["","","","ما عندكم ينفد وما عند الله باق ولنجزين الذين صبروا أجرهم بأحسن ما كانوا يعملون","ތިޔަބައިމީހުންގެ ގާތުގައިވާ އެއްޗެއް ހުސްވެގެން ހިނގައިދާނެތެވެ. އަދި ﷲގެ ހަޒުރަތު ގައިވާ އެއްޗެއް ދެމިހުންނާނެތެވެ. އަދި ހަމަކަށަވަރުން، ކެތްތެރިވީ މީހުންނަށް، އެއުރެން ޢަމަލު ކޮށްއުޅުނު އެންމެ ހެޔޮގޮތުގެ ދަރުމައިން، ތިމަންރަސްކަލާނގެ ޖަޒާ ދެއްވާހުށީމެވެ.","",""],["","","","من عمل صالحا من ذكر أو أنثى وهو مؤمن فلنحيينه حياة طيبة ولنجزينهم أجرهم بأحسن ما كانوا يعملون","މުއުމިނަކު ކަމުގައިވާ ޙާލު، ފިރިހެނުންގެ ތެރެއިންވިޔަސް، ނުވަތަ އަންހެނުންގެ ތެރެއިންވިޔަސް، ސާލިހު ޢަމަލެއް ކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އެމީހަކަށް ރަނގަޅު، ބާއްޖަވެރި ދިރިއުޅުމެއް، ތިމަންރަސްކަލާނގެ ދެއްވާހުށީމެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެން ޢަމަލު ކޮށް އުޅުނު އެންމެ ހެޔޮގޮތުގެ ދަރުމައިން، އެއުރެންނަށް، ތިމަންރަސްކަލާނގެ ޖަޒާ ދެއްވާހުށީމެވެ.","",""],["","","","فإذا قرأت القرآن فاستعذ بالله من الشيطان الرجيم","ފަހެ، ކަލޭގެފާނު ގުރްއާން ކިޔަވައި ވިދާޅުވާނަމަ، ފަހެ، ރަހުމަތުން ބޭރުކުރައްވާފައިވާ ޝައިތާނާގެ ކިބައިން ދުރުކުރެއްވުންއެދި، ﷲގެ ރައްކާތެރިކަމަށްއެދި ދަންނަވާށެވެ!","",""],["","","","إنه ليس له سلطان على الذين آمنوا وعلى ربهم يتوكلون","ހަމަކަށަވަރުން، އީމާންވެ، އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ވަކީލުކުރާމީހުންގެ މައްޗަށް އެއްވެސް ބާރެއް، އެ ޝައިތާނާއަކަށް ނުވެއެވެ.","",""],["","","","إنما سلطانه على الذين يتولونه والذين هم به مشركون","އޭނާއަށް ބާރު ލިބިގެންވާކަން ކަށަވަރީ، އޭނާގެ ވާގިވެރިކަން ލިބިގަންނަ މީހުންގެ މައްޗަށާއި، އެކަލާނގެއަށް ޝަރީކު ކޮށްއުޅޭ މީހުންގެ މައްޗަށެވެ.","",""],["","","","وإذا بدلنا آية مكان آية والله أعلم بما ينزل قالوا إنما أنت مفتر بل أكثرهم لا يعلمون","އެއް އާޔަތެއްގެ ތަނަށް، އެހެން އާޔަތެއް ތިމަންރަސްކަލާނގެ ބަދަލުކުރައްވައި ގެންނަވައިފި ހިނދު، ﷲ އެކަލާނގެ ބާވައިލައްވާ ތަކެތި މޮޅަށް ދެނެވޮޑިގެންވެތެވެ. އެއުރެން ބުނެތެވެ. ކަލޭގެފާނު ވާކަން ކަށަވަރީ، ދޮގުހަދާ މީހެއްކަމުގައެވެ. އަދި ކިއެއްތަ! އެއުރެންކުރެ ގިނަމީހުން ނުދަނެތެވެ.","",""],["","","","قل نزله روح القدس من ربك بالحق ليثبت الذين آمنوا وهدى وبشرى للمسلمين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހައްގު ގޮތުގައި އެ ފޮތް ބާވައިލެއްވީ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ޖިބްރީލުގެފާނެވެ. (އެއީ) އީމާންވި މީހުންނަށް ޘާބިތު ކަން ދެއްވުމަށްޓަކައެވެ. އަދި މުސްލިމުންނަށް އޮތް ހިދާޔަތެއް ކަމުގައްޔާއި، އުފާވެރި ޚަބަރެއް ކަމުގައެވެ.","",""],["","","","ولقد نعلم أنهم يقولون إنما يعلمه بشر لسان الذي يلحدون إليه أعجمي وهذا لسان عربي مبين","އެކަލޭގެފާނަށް އުނގަންނައިދެއްވަނީ، ހަމަކަށަވަރުން، އިންސާނު އެކޭ އެއުރެން ބުނެއުޅޭކަން، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގެންވަމެވެ. އެއުރެން، އެކަލޭގެފާނަށް އުނގަންނައިދޭކަމަށް ބުނާ މީހާގެ ބަހަކީ، ޢަޖަމީ ބަހެވެ. މިއީ ބަޔާންވެގެންވާ އަރަބި ބަހެވެ.","",""],["","","","إن الذين لا يؤمنون بآيات الله لا يهديهم الله ولهم عذاب أليم","ހަމަކަށަވަރުން، ﷲގެ އާޔަތްތަކަށް، އީމާން ނުވާ މީހުން (ދަންނާށެވެ!) ﷲ، އެއުރެންނަށް ތެދުމަގެއް ނުދައްކަވާނެތެވެ. އަދި ވޭންދެނިވި އަޒާބެއުރެންނަށްހުށްޓެވެ.","",""],["","","","إنما يفتري الكذب الذين لا يؤمنون بآيات الله وأولئك هم الكاذبون","ދޮގުހަދާކަން ކަށަވަރީ، ﷲގެ އާޔަތްތަކަށް އީމާން ނުވާ މީހުންނެވެ. އަދި އެއުރެންނީ ހަމަ، ދޮގުވެރިންނެވެ.","",""],["","","","من كفر بالله من بعد إيمانه إلا من أكره وقلبه مطمئن بالإيمان ولكن من شرح بالكفر صدرا فعليهم غضب من الله ولهم عذاب عظيم","އީމާންކަމަށް، އެމީހާގެ ހިތްހަމަޖެހިގެންވާ ޙާލު، މަޖުބޫރު ވެގެންވާ މީހާ މެނުވީ، އީމާން ވުމަށްފަހު، ﷲއަށް ކާފިރު ވެއްޖެމީހާ، އަދި އެހެނެއްކަމަކު (އެބަހީ: މަޖުބޫރު ވެގެންވިޔަސް) ކާފިރުކަމަށް ހިތްތަނަވަސް ވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންނަށް ﷲގެ ހަޒުރަތުން ކޯފާލެއްވުންހުށްޓެވެ. އަދި ބޮޑުވެގެންވާ އަޒާބު، އެއުރެންނަށްހުށްޓެވެ.","",""],["","","","ذلك بأنهم استحبوا الحياة الدنيا على الآخرة وأن الله لا يهدي القوم الكافرين","އެއީ ހަމަކަށަވަރުން، އެއުރެން، އާޚިރަތްގެ މައްޗަށް، ދުނިޔަވީ ހަޔާތް އިސްކުޅައުމުގެ ސަބަބުންނެވެ. އަދި ހަމަކަށަވަރުން، ކާފިރު ވީމީހުންނަކަށް، ﷲ، ތެދުމަގެއް ނުދައްކަވާނެތެވެ.","",""],["","","","أولئك الذين طبع الله على قلوبهم وسمعهم وأبصارهم وأولئك هم الغافلون","އެއުރެންނީ، އެއުރެންގެ ހިތްތަކުގައްޔާއި، އެއުރެންގެ ކަންފަތްތަކުގައްޔާއި، އެއުރެންގެ ލޯތަކުގައި، ﷲ ސިއްކަގައްސަވާފައިވާ މީހުންނެވެ. އަދި އެއުރެންނީ، ހަމަ، ޣާފިލު ވެގެންވާ މީހުންނެވެ.","",""],["","","","لا جرم أنهم في الآخرة هم الخاسرون","ޝައްކެއްނެތެވެ. ހަމަކަށަވަރުން، އާޚިރަތުގައި ގެއްލެނިވެގެންވާ މީހުންނަކީ، ހަމަ، އެއުރެންނެވެ.","",""],["","","","ثم إن ربك للذين هاجروا من بعد ما فتنوا ثم جاهدوا وصبروا إن ربك من بعدها لغفور رحيم","ދެން ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ (އެހީތެރިވެ) ވޮޑިގަތުންވަނީ، އެއުރެންނަށް އަނިޔާލިބި، އިމްތިހާނު ވެވުމަށްފަހު، ހިޖުރަ ކޮށް، ދެން ޖިހާދު ކޮށް، ކެތްތެރިވީ މީހުންނަށެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، އެއަށްފަހުވެސް ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","يوم تأتي كل نفس تجادل عن نفسها وتوفى كل نفس ما عملت وهم لا يظلمون","ކޮންމެ ނަފްސެއްވެސް، އެ ނަފްސެއް (ދިފާޢު ކޮށް) ޖަދަލުކުރުމަށް އަންނަ ދުވަސް (ހަނދުމަކުރާށެވެ!) އަދި ކޮންމެ ނަފްސަކަށްމެ، އެ ނަފްސެއް ކުޅަ ޢަމަލަކަށް (އެ ދުވަހުން) ފުރިހަމައަށް ޖަޒާ ދެއްވާނެތެވެ. އަދި އެއުރެންނަށް، ބޭއިންސާފެއް ނުކުރައްވާނޭމެއެވެ.","",""],["","","","وضرب الله مثلا قرية كانت آمنة مطمئنة يأتيها رزقها رغدا من كل مكان فكفرت بأنعم الله فأذاقها الله لباس الجوع والخوف بما كانوا يصنعون","އަމާންވެ، ހިތްހަމަޖެހިގެންވާ ރަށެއްގެ މިސާލުން، ﷲ މިސާލެއް ޖެއްސެވިއެވެ. ކޮންމެ ދިމާޔަކުން ތަނަވަސްވެގެންވާ ގޮތުގައި، އެ ރަށަށް ރިޒްގު އާދެތެވެ. ދެން ﷲގެ ނިއުމަތްތަކަށް އެ ރަށުގެ މީހުން ކާފިރު ވޫއެވެ. ދެން އެއުރެން ކޮށްއުޅުނު ކަންތަކުގެ ސަބަބުން، ބަނޑުހައިހޫނުކަމާއި، ބިރުވެރިކަމުގެ ފޭރާންލައްވައި، އެކަމުގެ ރަހަ އެއުރެންނަށް ﷲ ދެއްކެވިއެވެ.","",""],["","","","ولقد جاءهم رسول منهم فكذبوه فأخذهم العذاب وهم ظالمون","ހަމަކަށަވަރުން، އެއުރެންގެތެރެއިން، ރަސޫލަކު، އެއުރެންގެ ގާތަށް ވަޑައިގަތެވެ. ފަހެ، އެއުރެން އެ ރަސޫލާ ދޮގުކުޅައޫވެ. ދެން އެއުރެން އަނިޔާވެރިންކަމުގައިވާ ޙާލު، އެއުރެންގެ މައްޗަށް އަޒާބު އައެވެ.","",""],["","","","فكلوا مما رزقكم الله حلالا طيبا واشكروا نعمت الله إن كنتم إياه تعبدون","ފަހެ، ﷲ ތިޔަބައިމީހުންނަށް ރަނގަޅު ހަލާލު ތަކެތީގެ ގޮތުގައި ދެއްވި ރިޒްގުން ތިޔަބައިމީހުން ކައިއުޅޭށެވެ! އަދި ﷲގެ ނިއުމަތަށް ތިޔަބައިމީހުން ޝުކުރުކުރާށެވެ! (އެއީ) ހަމައެކަނި، އެކަލާނގެއަށް ތިޔަބައިމީހުން އަޅުކަންކުރާ ކަމުގައި ވާނަމައެވެ.","",""],["","","","إنما حرم عليكم الميتة والدم ولحم الخنزير وما أهل لغير الله به فمن اضطر غير باغ ولا عاد فإن الله غفور رحيم","ތިޔަބައިމީހުންނަށް، އެކަލާނގެ ހަރާމްކުރައްވާފައިވާކަން ކަށަވަރީ، މުޅަތަކެއްޗާއި، ލެޔާއި، އޫރުމަހާއި، ﷲ ފިޔަވައި އެހެން ފަރާތެއްގެ ނަންގަނެ ކަތިލާ ތަކެއްޗެވެ. ފަހެ، ނުކިޔަމަންތެރިވެ، ދެކޮޅުވެރިވުމެއް އަދި ހައްދުފަހަނަޅައިދިއުމެއް ނެތި، މަޖުބޫރު ވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ولا تقولوا لما تصف ألسنتكم الكذب هذا حلال وهذا حرام لتفتروا على الله الكذب إن الذين يفترون على الله الكذب لا يفلحون","ﷲއާމެދު، ތިޔަބައިމީހުން ދޮގުހެދުމަށްޓަކައި، ތިޔަބައިމީހުންގެ ދޫތަކުން ދޮގުތައްހަދައި، ސިފަކޮށް އުޅޭކަންތަކަށް، މިއީ ހަލާލުކަމެކޭ، އަދި މިއީ ހަރާމްކަމެކޭ ތިޔަބައިމީހުން ނުބުނާށެވެ! ހަމަކަށަވަރުން، ﷲއާމެދު، ދޮގުހަދާމީހުން ނުދިނޭހުށްޓެވެ.","",""],["","","","متاع قليل ولهم عذاب أليم","(އެއީ) ކުޑަކުޑަ ވަގުތީ އަރާމެކެވެ. އަދި އެއުރެންނަށް ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["","","","وعلى الذين هادوا حرمنا ما قصصنا عليك من قبل وما ظلمناهم ولكن كانوا أنفسهم يظلمون","މީގެކުރިން، ކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ (ވަހީކުރައްވައި) ކިޔައިދެއްވި ކަންތައް، ޔަހޫދީ ވީ މީހުންގެ މައްޗަށް، ތިމަންރަސްކަލާނގެ ހަރާމްކުރެއްވީމެވެ. ތިމަންރަސްކަލާނގެ އެއުރެންނަށް އަނިޔާވެރިވެވޮޑިއެއް ނުގަންނަވަމެވެ. އެހެނެއް ކަމަކު، އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް އަނިޔާވެރިވާ ކަމުގައި، އެއުރެން ވޫއެވެ.","",""],["","","","ثم إن ربك للذين عملوا السوء بجهالة ثم تابوا من بعد ذلك وأصلحوا إن ربك من بعدها لغفور رحيم","ދެން ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ (ފާފަފުއްސެވުން) ވަނީ، ނޭނގިތިބެގެން، ނުބައިކަންތައްކޮށް، ދެން އެއަށްފަހު ތައުބާވެ، އިސްލާހު ވެގަތް ބަޔަކަށެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، އެކަންތަކަށްފަހުވެސް، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","إن إبراهيم كان أمة قانتا لله حنيفا ولم يك من المشركين","ހަމަކަށަވަރުން، އިބްރާހީމްގެފާނީ، ﷲއަށް ކިޔަމަންތެރިވެވަޑައިގެން، ބާތިލު މަގުން އެއްކިބާވެ، ސީދާމަގުގައި ހުންނެވި، ހެޔޮކަމުގެ ހުރިހާކަމެއް އެކުލެވިގެންވާ އުއްމަތެއް ކަމުގައިވިއެވެ. އަދި ޝަރީކުކުރާމީހުންގެ ތެރެއިން، އެކަލޭގެފާނު ނުވެތެވެ.","",""],["","","","شاكرا لأنعمه اجتباه وهداه إلى صراط مستقيم","އެކަލާނގެ ދެއްވި ނިއުމަތްތަކަށް، ޝުކުރުކުރައްވާ ބޭކަލަކު ކަމުގައި އެކަލޭގެފާނު ވިއެވެ. އެކަލާނގެ، އެކަލޭގެފާނު ޚިޔާރުކުރެއްވިއެވެ. އަދި ސީދާވެގެންވާ މަގަށް، އެކަލޭގެފާނަށް މަގު ދެއްކެވިއެވެ.","",""],["","","","وآتيناه في الدنيا حسنة وإنه في الآخرة لمن الصالحين","އަދި ދުނިޔޭގައި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ހެޔޮކަން ދެއްވީމެވެ. އަދި ހަމަކަށަވަރުން، އާޚިރަތުގައި، އެކަލޭގެފާނު ވަނީ، ސާލިހު ންގެތެރެއިންކަން ކަށަވަރެވެ.","",""],["","","","ثم أوحينا إليك أن اتبع ملة إبراهيم حنيفا وما كان من المشركين","ދެން ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނަށް ވަހީކުރެއްވީމެވެ. ބާތިލު މަގުން އެއްކިބާވެ، ސީދާމަގުގައިވާ އިބްރާހީމްގެފާނުގެ ދީނަށް، ކަލޭގެފާނު ތަބާ ވެވަޑައިގަންނަވާށެވެ! ފަހެ، މުޝްރިކުންގެ ތެރެއިން އެކަލޭގެފާނު ނުވެތެވެ.","",""],["","","","إنما جعل السبت على الذين اختلفوا فيه وإن ربك ليحكم بينهم يوم القيامة فيما كانوا فيه يختلفون","ހޮނިހިރުދުވަހުގެ ހުރުމަތް ތެރިކަން ލައްވާފައިވާކަން ކަށަވަރީ، އެދުވަހާމެދު ޚިލާފު ވެގެން އުޅުނު މީހުންގެ މައްޗަށެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެން ޚިލާފުވެ އުޅުނު ކަންތަކާމެދު، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ގިޔާމަތް ދުވަހުން އެއުރެންގެމެދުގައި، ހުކުމްކުރައްވާނެކަން ކަށަވަރެވެ.","",""],["","","","ادع إلى سبيل ربك بالحكمة والموعظة الحسنة وجادلهم بالتي هي أحسن إن ربك هو أعلم بمن ضل عن سبيله وهو أعلم بالمهتدين","ހިކުމަތާއި، ރިވެތި ވައުޒާއެކު، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ މަގަށް، ކަލޭގެފާނު ގޮވައިލައްވާށެވެ! އަދި ރިވެތި ގޮތުގައި އެއުރެންނާ ޖަދަލުކުރައްވާށެވެ! ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، އެކަލާނގެ މަގުން އެއްކިބާވެގެންވާ މީހުން، މޮޅަށް ދެނެވޮޑިގެންވެތެވެ. އަދި ތެދުމަގުލިބިގެންވާ މީހުންވެސް، މޮޅަށް ދެނެވޮޑިގެންވަނީ އެކަލާނގެއެވެ.","",""],["","","","وإن عاقبتم فعاقبوا بمثل ما عوقبتم به ولئن صبرتم لهو خير للصابرين","އަދި ތިޔަބައިމީހުން، އުގޫބާތް ދޭނަމަ، ތިޔަބައިމީހުންނަށް އުގޫބާތް ލިބުނު ފަދަޔަކުން، ފަހެ، ތިޔަބައިމީހުން އުގޫބާތް ދޭށެވެ! އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ކެތްކޮށްފިނަމަ، އެ ގޮތް، ކެތްތެރިންނަށް ހެޔޮކަން ބޮޑުވެގެންވާކަން ކަށަވަރެވެ.","",""],["","","","واصبر وما صبرك إلا بالله ولا تحزن عليهم ولا تك في ضيق مما يمكرون","އަދި ކަލޭގެފާނު ކެތްކުރައްވާށެވެ! އަދި ﷲގެ ވާގިފުޅުން މެނުވީ، ކަލޭގެފާނު ކެތްތެރިވެވަޑައިގަތުމެއް ނުވެތެވެ. އަދި އެއުރެންގެ މައްޗަށް ކަލޭގެފާނު ހިތާމަ ނުކުރައްވާށެވެ! އަދި އެއުރެން ރާވާ މަކަރުވެރި ރޭވުންތަކުން ހިތްޕުޅުދަތިވުމެއްގެ ތެރޭގައި، ކަލޭގެފާނު ވެވަޑައިނުގަންނަވާށެވެ!","",""],["","","","إن الله مع الذين اتقوا والذين هم محسنون","ހަމަކަށަވަރުން، ﷲ ވޮޑިގެންވަނީ، ތަގުވާވެރިވި މީހުންނާ އެކުގައެވެ. އަދި އިހްސާން ތެރިންނާވެސް އެކުގައެވެ.","",""],["","","","بسم الله الرحمن الرحيم سبحان الذي أسرى بعبده ليلا من المسجد الحرام إلى المسجد الأقصى الذي باركنا حوله لنريه من آياتنا إنه هو السميع البصير","އެކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! އެކަލާނގެއީ، އަލްމަސްޖިދުލް ހަރާމުން، އަލްމަސްޖިދުލް އަގްޞާއަށް އެކަލާނގެ އަޅާ، ރޭގަނޑުން ބައެއްގައި ގެންދެވި ރަސްކަލާނގެއެވެ. އެއީ އެތާނގެ ވަށައިގެން، ތިމަންރަސްކަލާނގެ ބަރަކާތް ލެއްވި ތަނެވެ. (އެއީ) ތިމަންރަސްކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެކިތަކުގެ ތެރެއިން ބައެއް، އެކަލޭގެފާނަށް ދެއްކެވުމަށްޓަކައެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وآتينا موسى الكتاب وجعلناه هدى لبني إسرائيل ألا تتخذوا من دوني وكيلا","އަދި ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް ފޮތް ދެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އިސްރާއީލުގެދަރިންނަށް ތެދުމަގެއްކަމުގައި އެ ފޮތް ލެއްވީމެވެ. (ވަހީކުރައްވަމުންނެވެ.) ތިމަންރަސްކަލާނގެ ފިޔަވައި (އެހެންފަރާތެއް) ވަކީލެއް ކަމުގައި ތިޔަބައިމީހުން ނުހިފާށެވެ!","",""],["","","","ذرية من حملنا مع نوح إنه كان عبدا شكورا","ތިމަންރަސްކަލާނގެ ނޫޙުގެފާނާ އެކުގައި އުފުއްލެވި ދަރިފަސްކޮޅުގެ މީހުންނޭވެ! ހަމަކަށަވަރުން، ޝުކުރުވެރިވާ އަޅަކު ކަމުގައި އެކަލޭގެފާނުވިއެވެ.","",""],["","","","وقضينا إلى بني إسرائيل في الكتاب لتفسدن في الأرض مرتين ولتعلن علوا كبيرا","އަދި ތިމަންރަސްކަލާނގެ، އިސްރާއީލުގެދަރިންނަށް، ފޮތުގައި (އެބަހީ: ތައުރާތުގައި) ކަނޑައަޅުއްވައި އެންގެވީމެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ދެފަހަރެއްގެމަތިން ބިމުގައި ފަސާދަކުރާނޫއެވެ. އަދި ހަމަކަށަވަރުން، ބޮޑުވެގެންވާ ބޮޑާވުމަކުން ތިޔަބައިމީހުން ބޮޑާވާނޫއެވެ.","",""],["","","","فإذا جاء وعد أولاهما بعثنا عليكم عبادا لنا أولي بأس شديد فجاسوا خلال الديار وكان وعدا مفعولا","ފަހެ، އެ ދެފަހަރުންކުރެ ފުރަތަމަ ފަހަރުގެ ވައުދުފުޅު އައިހިނދު، ގަދަފަދަވެގެންވާ ބާރެއްގެވެރި އަޅުންތަކެއް، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންގެ މައްޗަށް ފޮނުއްވީމެވެ. ފަހެ، އެއުރެން (ތިޔަބައިމީހުންގެ ރަށުގެ) ގޯތިގެދޮރުގެ ތެރެޔަށް ވަދެގެންދިޔައޫއެވެ. އަދި ފުރިހަމަވެގެންވާ ވައުދު ފުޅެއްކަމުގައި، އެ ވައުދުފުޅު ވިއެވެ.","",""],["","","","ثم رددنا لكم الكرة عليهم وأمددناكم بأموال وبنين وجعلناكم أكثر نفيرا","ދެން އެއުރެންގެ މައްޗަށް، ތިޔަބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ އެނބުރި އައުމެއް (އެބަހީ: ވެރިކަމާއި ބާރު އަލުން) ދެއްވީމެވެ. އަދި ދަރިންނާއި، މުދާތަކުން ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް މަދަދު ދެއްވީމެވެ. އަދި މީހުންގެ ގޮތުން، ގިނަބަޔަކު ކަމުގައި ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން ލެއްވީމެވެ.","",""],["","","","إن أحسنتم أحسنتم لأنفسكم وإن أسأتم فلها فإذا جاء وعد الآخرة ليسوءوا وجوهكم وليدخلوا المسجد كما دخلوه أول مرة وليتبروا ما علوا تتبيرا","ތިޔަބައިމީހުން ހެޔޮކޮށް ކަންތައް ކުޅަނަމަ، އެ ހެޔޮކަންތައް ކުޅައީ، ހަމަ ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސު ތަކަށެވެ. އަދި ނުބައިކޮށް ކަންތައް ކުޅަނަމަވެސް، (އެ ނުބައިކަންތައް ކުޅައީ) ހަމަ އެ ނަފްސު ތަކަށެވެ. ފަހެ، ދެވަނަފަހަރަށް ވައުދުފުޅު އައިހިނދު (ތިޔަބައިމީހުންގެ އަދާވަތް ތެރިން ފޮނުއްވީމެވެ.) އެއުރެންގެ ސަބަބުން ތިޔަބައިމީހުންގެ މޫނުމަތިން ހިތާމައިގެ އަސަރުތައް ފާޅުވުމަށްޓަކައެވެ. އަދި ފުރަތަމަ ފަހަރު އެއުރެން އެތަނަށް ވަންފަދައިން، މިސްކިތަށް (އެބަހީ: އަލްމަސްޖިދުލް އަގްޞާއަށް) ވަނުމަށްޓަކައެވެ. އަދި އެއުރެން ވެރިވެގަތް ތަންތަން ހަލާކުކޮށް، ސުންނާފަތި ކުރުމަށްޓަކައެވެ.","",""],["","","","عسى ربكم أن يرحمكم وإن عدتم عدنا وجعلنا جهنم للكافرين حصيرا","ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ، ތިޔަބައިމީހުންނަށް (އަފޫކުރައްވައި) ރަހުމަތް ލެއްވުން ގާތްވެގެންވެއެވެ. އަދި ތިޔަބައިމީހުން (ފަސާދަކުރުމަށް) އެނބުރި އަތުވެއްޖެނަމަ، ތިމަންރަސްކަލާނގެ (އުގޫބާތް ދެއްވުމަށް) އެނބުރި ވޮޑިގެންފާހުށީމެވެ. އަދި ކާފިރުންނަށް ހުރަގެއެއް ކަމުގައި، ތިމަންރަސްކަލާނގެ ނަރަކަ ލެއްވީމެވެ.","",""],["","","","إن هذا القرآن يهدي للتي هي أقوم ويبشر المؤمنين الذين يعملون الصالحات أن لهم أجرا كبيرا","ހަމަކަށަވަރުން، މި ގުރްއާން، އެންމެ ސީދާ މަގަށް މަގުދައްކައެވެ. އަދި ހަމަކަށަވަރުން، ސާލިހު ޢަމަލުތައްކުރާ މުއުމިނުންނަށް ބޮޑުވެގެންވާ ދަރުމައެއް ހުރިކަމުގެ އުފާވެރި ޚަބަރު ދެއެވެ.","",""],["","","","وأن الذين لا يؤمنون بالآخرة أعتدنا لهم عذابا أليما","އަދި ހަމަކަށަވަރުން، އާޚިރަތަށް އީމާން ނުވާމީހުންނަށް، ވޭންދެނިވި އަޒާބެއް، ތިމަންރަސްކަލާނގެ ތައްޔާރުކުރެއްވިކަމުގެ ޚަބަރު ވެސްމެއެވެ.","",""],["","","","ويدع الإنسان بالشر دعاءه بالخير وكان الإنسان عجولا","އިންސާނާ، ހެޔޮކަމަށްއެދި ދުއާކުރާ ފަދައިން، ނުބައިކަމަށްވެސް އެދި ދުއާކުރެތެވެ. އަދި އިންސާނާއަކީ، އަވަސްވެގަންނަ މީހަކު ކަމުގައިވިއެވެ.","",""],["","","","وجعلنا الليل والنهار آيتين فمحونا آية الليل وجعلنا آية النهار مبصرة لتبتغوا فضلا من ربكم ولتعلموا عدد السنين والحساب وكل شيء فصلناه تفصيلا","ރޭގަނޑާއި، ދުވާލަކީ، ދެ ހެކިކަމުގައި، ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ. ފަހެ، ރޭގަނޑުގެ ހެކިން ނޫރު ފުހެލެއްވީމެވެ. އަދި ދުވާލުގެ ހެކި އެއީ (ތަންތަން) ދައްކައިދޭ އެއްޗެއްކަމުގައި ލެއްވީމެވެ. (އެއީ) ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން، ތިޔަބައިމީހުން، ފަޟްލު ވަންތަކަން އެދި އުޅުމަށްޓަކައެވެ. އަދި އަހަރުތަކުގެ އަދަދާއި، ހިސާބު، ތިޔަބައިމީހުން ދެނެގަތުމަށްޓަކައެވެ. އަދި ކޮންމެ ކަމެއްމެ ތަފްޞީލު ކޮށް ތިމަންރަސްކަލާނގެ ބަޔާންކޮށްދެއްވީމެވެ.","",""],["","","","وكل إنسان ألزمناه طائره في عنقه ونخرج له يوم القيامة كتابا يلقاه منشورا","އަދި ކޮންމެ އިންސާނަކުމެ، އޭނާ ކުޅަ ޢަމަލު، އޭނާގެ ކަރުގައި ތިމަންރަސްކަލާނގެ އެޅުއްވީމެވެ. އަދި ގިޔާމަތް ދުވަހުން، ތިމަންރަސްކަލާނގެ އެމީހަކަށް ފޮތެއް ނެރުއްވާހުށީމެވެ. އެ ފޮތް ނިއުޅައިލެވިގެންވާ ޙާލުގައި، އޭނާ ދެކޭނެތެވެ.","",""],["","","","اقرأ كتابك كفى بنفسك اليوم عليك حسيبا","(އަދި އަންގަވާނެތެވެ.) ތިބާގެ ފޮތް ތިބާ ކިޔާށެވެ! މިއަދު ތިބާގެ މައްޗަށް ހިސާބުކުރާ މީހަކަށް، ތިބާގެ އަމިއްލަނަފްސު ފުދެއެވެ.","",""],["","","","من اهتدى فإنما يهتدي لنفسه ومن ضل فإنما يضل عليها ولا تزر وازرة وزر أخرى وما كنا معذبين حتى نبعث رسولا","ތެދުމަގު ލިބިގެންފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާ އެ ތެދުމަގު ލިބިގަންނަކަން ކަށަވަރީ، އެމީހާގެ އަމިއްލަ ނަފްސުގެ ލާބައަށެވެ. އަދި މަގުފުރެދިއްޖެ މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާ އެ މަގުފުރެދޭކަން ކަށަވަރީ، އެ ނަފްސުގެ ހަލާކަށެވެ. އަދި ފާފަވެރި އެއްވެސް ނަފްސެއް، އެހެން ނަފްސެއްގެ ފާފައެއް ނުއުފުލާނެތެވެ. އަދި ތިމަންރަސްކަލާނގެ ރަސޫލަކު ފޮނުއްވައިފުމަށް ދާނދެން (އެއްވެސްބަޔަކަށް) އަޒާބު ދެއްވުމަކަށް ތިމަންރަސްކަލާނގެ ކަނޑައެއް ނާޅުއްވަމެވެ.","",""],["","","","وإذا أردنا أن نهلك قرية أمرنا مترفيها ففسقوا فيها فحق عليها القول فدمرناها تدميرا","އަދި ރަށެއް ހަލާކު ކުރެއްވުމަށް، ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވައިފިނަމަ، އެ ރަށެއްގެ ތަނަވަސްކަމުގެ އަހުލުވެރިންނަށް ތިމަންރަސްކަލާނގެ (ކިޔަމަންގަތުމަށް) އަމުރުކުރައްވަމެވެ. ދެން އެއުރެން އެ ރަށުގައި ފާސިދު ޢަމަލު ކޮށް، ކިޔަމަންތެރިކަމުން ބޭރުވެގަނެތެވެ. ދެން ކޯފާގެ ބަސްފުޅު އެއުރެންގެ މައްޗަށް ހައްގު ވެދެތެވެ. ދެން ތިމަންރަސްކަލާނގެ އެރަށެއް މުޅިން ހަލާކު ކުރައްވައި ނެތިކުރައްވަމެވެ.","",""],["","","","وكم أهلكنا من القرون من بعد نوح وكفى بربك بذنوب عباده خبيرا بصيرا","ނޫޙުގެފާނަށްފަހު، ކިތައްކިތައް ޖީލުގެ މީހުން ތިމަންރަސްކަލާނގެ ހަލާކުކުރައްވައި، ނެތިކުރެއްވިންހެއްޔެވެ؟ އެކަލާނގެ އަޅުތަކުންގެ ފާފަތަކުގެ ޚަބަރު، މޮޅަށް ދެނެވޮޑިގެންވާ (އަދި) މޮޅަށް ބައްލަވާވޮޑިގެންވާ ކަލަކު ކަމުގައިވުމަށް ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ފުދެތެވެ.","",""],["","","","من كان يريد العاجلة عجلنا له فيها ما نشاء لمن نريد ثم جعلنا له جهنم يصلاها مذموما مدحورا","ދުނިޔޭގެ އަރާމަށް އެދޭމީހާ (ދަންނާށެވެ!) ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާކަމެއް، ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް އަވަސްކޮށްދެއްވާ ހުށީމެވެ. ދެން އެމީހަކަށްޓަކައި، ތިމަންރަސްކަލާނގެ ނަރަކަ ލެއްވީމެވެ. މަލާމާތްލިބި، ރަހުމަތުން ދުރުކުރައްވާފައިވާ ޙާލު، އެ ނަރަކައަށް އެމީހަކު ވަންނާނެތެވެ.","",""],["","","","ومن أراد الآخرة وسعى لها سعيها وهو مؤمن فأولئك كان سعيهم مشكورا","އަދި މުއުމިނަކު ކަމުގައިވާ ޙާލު، އާޚިރަތަށް އެދި، އެދުވަހަކަށްޓަކައި މަސައްކަތްކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ، އެއުރެންގެ މަސައްކަތް މަގްބޫލް ވެވި، ޝުކުރު ލިބިގެންވާ މީހުންނެވެ.","",""],["","","","كلا نمد هؤلاء وهؤلاء من عطاء ربك وما كان عطاء ربك محظورا","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ދެއްވާ ދެއްވުންތަކުން މިބައިމީހުންނާއި އެއުރެންނާއި، އެންމެންނަށް، ތިމަންރަސްކަލާނގެ ދެއްވަމެވެ. ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ދެއްވާ ދެއްވުމަކީ، މަނާކުރެވޭނޭ އެއްޗެއް ކަމުގައި ނުވެތެވެ.","",""],["","","","انظر كيف فضلنا بعضهم على بعض وللآخرة أكبر درجات وأكبر تفضيلا","ތިމަންރަސްކަލާނގެ އެއުރެންކުރެ އެއްބަޔަކު އަނެއްބަޔަކަށްވުރެ މާތްކުރައްވާފައިވަނީ، ކޮންފަދައަކުންކަން ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާށެވެ! އަދި ހަމަކަށަވަރުން، ދަރަޖައިގެގޮތުން އާޚިރަތް މާބޮޑެވެ. އަދި މާތްކުރެއްވުމުގެ ގޮތުންވެސް މާބޮޑުމެއެވެ.","",""],["","","","لا تجعل مع الله إلها آخر فتقعد مذموما مخذولا","ﷲއާއެކު އެހެން އިލާހަކު ނުލާށެވެ! ފަހެ، އޭރުން މަލާމާތްލިބި، ނިކަމެތިވެގެންވާ ޙާލު، ތިބާ އިންނަންޖެހިދާނެތެވެ.","",""],["","","","وقضى ربك ألا تعبدوا إلا إياه وبالوالدين إحسانا إما يبلغن عندك الكبر أحدهما أو كلاهما فلا تقل لهما أف ولا تنهرهما وقل لهما قولا كريما","އެކަލާނގެއަށް މެނުވީ، ތިޔަބައިމީހުން އަޅުކަން ނުކުޅައުމަށާއި، މައިންބަފައިންނަށް ހެޔޮކޮށް ހިތުމަށް، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ކަނޑައަޅުއްވައި އެންގެވިއެވެ. އެ ދެމީހުންކުރެ އެކަކު، ނުވަތަ އެ ދެމީހުން ތިބާގެގާތުގައި ތިބެ، މުސްކުޅިކަމާ ހަމަޔަށް ފޯރައްޖެނަމަ، އެދެމީހުންނަށް އުއްފު ވެސް ނުބުނާށެވެ! (އެބަހީ: ނުރުހުމުގެ ކިތަންމެ ކުޑަ ބަހެއްވިޔަސް ނުބުނާށެވެ!) އަދި އެ ދެމީހުންނަށް، އަޑުލައި ނުހަދާށެވެ! އަދި މާތް ބަހަކުން އެ ދެމީހުންނަށް ބަސްބުނާށެވެ!","",""],["","","","واخفض لهما جناح الذل من الرحمة وقل رب ارحمهما كما ربياني صغيرا","އަދި އޯގާވެރިވުމުގެގޮތުން، ނިކަމެތިކަމުގެ ފިޔަ، ތިބާ އެ ދެމީހުންނަށްޓަކައި ތިރިކޮށްލާށެވެ! އަދި ބުނާށެވެ! އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! ކުޑަކުއްޖަކު ކަމުގައި މިއަޅާވީދުވަހު، އެދެމީހުން މިއަޅާ ބަލައިބޮޑުކުރި ފަދައިން، އެ ދެމީހުންނަށް ރަހުމަތް ލައްވައިފާނދޭވެ!","",""],["","","","ربكم أعلم بما في نفوسكم إن تكونوا صالحين فإنه كان للأوابين غفورا","ތިޔަބައިމީހުންގެ ހިތްތަކުގައިވާ ކަންތައް ދެނެވޮޑިގަތުންބޮޑީ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއެވެ. ތިޔަބައިމީހުންނީ، ސާލިހު ބަޔަކުކަމުގައިވާނަމަ، ފަހެ، ހަމަކަށަވަރުން، އެކަލާނގެ ހަޒުރަތަށް ރުޖޫއަވާ މީހުންނަށް، ގިނަގިނައިން ފާފަފުއްސަވާ ރަސްކަލާނގެކަމުގައި އެކަލާނގެ ވޮޑިގެންވެއެވެ.","",""],["","","","وآت ذا القربى حقه والمسكين وابن السبيل ولا تبذر تبذيرا","ގާތްތިމާގެ މީހާއަށް، އޭނާގެ ހައްގު ދޭށެވެ! އަދި މިސްކީނަށާއި، ދަތުރުވެރިޔާއަށްވެސްމެއެވެ. އަދި ގިނަގިނައިން އިސްރާފު ނުކުރާހުށިކަމެވެ!","",""],["","","","إن المبذرين كانوا إخوان الشياطين وكان الشيطان لربه كفورا","ހަމަކަށަވަރުން، އިސްރާފުކުރާ މީހުންނީ، ޝައިތާނުންގެ އަޚުން ކަމުގައިވޫއެވެ. އަދި ޝައިތާނާ، އޭނާގެ ވެރިރަސްކަލާނގެއަށް ވަރަށް ބޮޑަށް ކާފިރުވާ ކަމުގައިވިއެވެ.","",""],["","","","وإما تعرضن عنهم ابتغاء رحمة من ربك ترجوها فقل لهم قولا ميسورا","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައުމަށް އެދިވަޑައިގަންނަވާ ރަހުމަތެއްގެ އެދުމުގައި، އެއުރެންނާ ދުރުހެލިވެވަޑައިގަންނަވާނަމަ، ފަހެ، މަޑުމައިތިރި ބަހަކުން އެއުރެންނަށް ބަސް ވިދާޅުވާށެވެ!","",""],["","","","ولا تجعل يدك مغلولة إلى عنقك ولا تبسطها كل البسط فتقعد ملوما محسورا","ތިބާގެ ކަނދުރާއާއެކު ކަސްތަޅު އެޅިގެންވާ އެއްޗެއްކަމުގައި، ތިބާގެ އަތް ނުހަދާށެވެ! އަދި އެ އަތް މުޅިން ފަތުރައިވެސްނުލާށެވެ! ފަހެ، އޭރުން މަލާމާތްލިބި، ހިތާމަ ލިބިގެންވާ ޙާލު، ތިބާ އިންނަން ޖެހިދާނެއެވެ.","",""],["","","","إن ربك يبسط الرزق لمن يشاء ويقدر إنه كان بعباده خبيرا بصيرا","ހަމަކަށަވަރުން، ތިބާގެ ވެރިރަސްކަލާނގެ، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ރިޒްގު ތަނަވަސްކޮށްދެއްވަތެވެ. އަދި އެކަލާނގެ (އިރާދަކުރައްވާ މީހަކަށް ރިޒްގު) ދަތިކުރައްވަތެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، އެކަލާނގެ އަޅުތަކުންގެ ޚަބަރު މޮޅަށްދެނެވޮޑިގެންވާ، މޮޅަށްބައްލަވާވޮޑިގެންވާ ކަލަކު ކަމުގައިވެއެވެ.","",""],["","","","ولا تقتلوا أولادكم خشية إملاق نحن نرزقهم وإياكم إن قتلهم كان خطئا كبيرا","އަދި ފަގީރު ވެދާނެކަމަށް ބިރުން، ތިޔަބައިމީހުންގެ ދަރިން ނުމަރާށެވެ! އެކުދިންނަށާއި، އަދި ތިޔަބައިމީހުންނަށް ރިޒްގު ދެއްވަނީ، ތިމަންރަސްކަލާނގެއެވެ. ހަމަކަށަވަރުން، އެ ދަރިން މެރުން އެއީ ބޮޑުވެގެންވާ ފާފައެއް ކަމުގައިވިއެވެ.","",""],["","","","ولا تقربوا الزنى إنه كان فاحشة وساء سبيلا","އަދި ތިޔަބައިމީހުން ޒިނޭއާ ގާތްނުވާށެވެ! ހަމަކަށަވަރުން، އެއީ ހުތުރުކަން ބޮޑުވެގެންވާ ފާފައެއް ކަމުގައިވިއެވެ. އަދި މަގެއްގެ ގޮތުން އެކަންތައް ހާދަހާ ނުބައިވެގެންވެއެވެ.","",""],["","","","ولا تقتلوا النفس التي حرم الله إلا بالحق ومن قتل مظلوما فقد جعلنا لوليه سلطانا فلا يسرف في القتل إنه كان منصورا","އަދި ތިޔަބައިމީހުން، ﷲ ހުރުމަތް ތެރިކުރައްވާފައިވާ ނަފްސެއް ހައްގަކާ ލައިގެންމެނުވީ ނުމަރާށެވެ! އަދި އަނިޔާގެގޮތުގައި، މަރައިލެވޭމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އެމީހާގެ ވަލީވެރިޔާއަށް، ތިމަންރަސްކަލާނގެ ބާރެއް ދެއްވީމެވެ. ފަހެ، ގަތުލުކުރުމުގައި އޭނާ އިސްރާފު ނުކުރާހުށިކަމެވެ! ހަމަކަށަވަރުން، އެ ވަލީވެރިޔާއަކީ، ނަސްރު ލިބިގެންވާ މީހެއް ކަމުގައިވިއެވެ.","",""],["","","","ولا تقربوا مال اليتيم إلا بالتي هي أحسن حتى يبلغ أشده وأوفوا بالعهد إن العهد كان مسئولا","އަދި ޔަތީމު ކުއްޖާ ބޮޑުވެ ތަޞައްރަފު ފުދިއްޖައުމަށް ދާނދެން، ރަނގަޅުގޮތުން މެނުވީ ތިޔަބައިމީހުން އޭނާގެ މުދަލާ ގާތްނުވާށެވެ! އަދި ތިޔަބައިމީހުން، އަހުދު ފުއްދާށެވެ! ހަމަކަށަވަރުން، އަހުދަކީ (އެއާމެދު) ސުވާލުކުރައްވާނޭ ކަމެއްކަމުގައި ވިއެވެ.","",""],["","","","وأوفوا الكيل إذا كلتم وزنوا بالقسطاس المستقيم ذلك خير وأحسن تأويلا","އަދި ތިޔަބައިމީހުން މިނާހިނދު، މިނުން ހަމަކޮށް ފުރިހަމަކުރާށެވެ! އަދި ސީދާވެގެންވާ ހަމަތިލަފަތުން ކިރާށެވެ! އެގޮތް (ތިޔަބައިމީހުންނަށް) ހެޔޮކަން ބޮޑެވެ. އަދި ނަތީޖާގެގޮތުން ރިވެތިކަން ބޮޑުމެއެވެ.","",""],["","","","ولا تقف ما ليس لك به علم إن السمع والبصر والفؤاد كل أولئك كان عنه مسئولا","އަދި ތިބާޔަށް އެކަމަކާމެދު އެނގުމެއް ނުވާކަމަކަށް، ތިބާ ތަބާ ނުވާށެވެ! ހަމަކަށަވަރުން، އިވުމާއި، ފެނުމާއި، ހިތާއި، މިއިން ކޮންމެ ކަމަކީ، އެއާމެދު ސުވާލުކުރައްވާނެ ކަމެއްކަމުގައިވިއެވެ.","",""],["","","","ولا تمش في الأرض مرحا إنك لن تخرق الأرض ولن تبلغ الجبال طولا","އަދި ތިބާ، ބޮޑާވެގެން ބިމުގައި ހިނގައިނޫޅޭށެވެ! ހަމަކަށަވަރުން، ތިބާޔަކަށް ބިންގަނޑު ފޫވައްޓައެއް ނުލެވޭނެތެވެ. އަދި ފަރުބަދަތަކާ ހަމަޔަށް ދިގުވެގެންވެސް ތިބާޔަކަށް ނުދެވޭނެތެވެ.","",""],["","","","كل ذلك كان سيئه عند ربك مكروها","އެ އެންމެހާ ކަންތަކުގެ ތެރެއިން، ނުބައިކަންތައް، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ނުރުއްސަވާ ކަންތައް ކަމުގައިވިއެވެ.","",""],["","","","ذلك مما أوحى إليك ربك من الحكمة ولا تجعل مع الله إلها آخر فتلقى في جهنم ملوما مدحورا","އެއީ ހިކުމަތްގެތެރެއިން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ކަލޭގެފާނަށް ވަހީކުރެއްވި ކަންތަކުގެ ތެރެއިންވާ ކަންކަމެވެ. އަދި ﷲއާއެކު އެހެން އިލާހަކު ނުލާށެވެ! ފަހެ، އޭރުން މަލާމާތްލިބި، ރަހުމަތުން ދުރުކުރައްވާފައިވާ ޙާލު، ޖަހައްނަމަށް އެއްލައިލައްވާނެތެވެ.","",""],["","","","أفأصفاكم ربكم بالبنين واتخذ من الملائكة إناثا إنكم لتقولون قولا عظيما","ފަހެ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ، ތިޔަބައިމީހުންނަށް ފިރިހެންދަރިން ހާއްސަކުރެއްވީހެއްޔެވެ؟ އަދި އެކަލާނގެ، މަލާއިކަތުންގެ ތެރެއިން އަންހެންދަރިން ހިއްޕެވީހެއްޔެވެ؟ ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ތިޔަ ބުނަނީ، ބޮޑުވެގެންވާ ބަހެކެވެ.","",""],["","","","ولقد صرفنا في هذا القرآن ليذكروا وما يزيدهم إلا نفورا","ތިމަންރަސްކަލާނގެ (ވައުދާއި، ވަޢީދާއި، މިސާލާއި، ޙިކަމު ފަދަ) ހުރިހާކަމެއް، މި ގުރްއާންގައި ބަޔާންކުރެއްވީމެވެ. އެއީ އެއުރެން ހަނދުމަކުރުމަށްޓަކައެވެ. (އެކަމަކު) އެއިން ނަފުރަތުވެ، ދުރުހެލިވުންމެނުވީ، އެއުރެންނަކަށް އިތުރެއް ނުކުރެތެވެ.","",""],["","","","قل لو كان معه آلهة كما يقولون إذا لابتغوا إلى ذي العرش سبيلا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއުރެން ބުނާފަދައިން، އެކަލާނގެއާއެކު އިލާހުންތަކެއް ވާނަމަ، އެހިނދު، ޢަރްޝުގެ ވެރިރަސްކަލާނގެއާ ދެކޮޅަށް މަގެއް ހޯދުމަށް، އެ އިލާހު ންތައް އެދުނީސްކަން ކަށަވަރެވެ.","",""],["","","","سبحانه وتعالى عما يقولون علوا كبيرا","އެއުރެން ބުނާ ބުނުމުން، އެކަލާނގެ ހުސްތާހިރު ވެވޮޑިގެންވެއެވެ. އަދި ބޮޑުވެގެންވާ މަތިވެރިވުމަކުން، އެކަލާނގެ މަތިވެރިވެވޮޑިގެންވެއެވެ.","",""],["","","","تسبح له السماوات السبع والأرض ومن فيهن وإن من شيء إلا يسبح بحمده ولكن لا تفقهون تسبيحهم إنه كان حليما غفورا","ހަތް އުޑާއި، ބިމާއި، އެތަންތާނގައިވާހާ ބަޔަކު، އެކަލާނގެއަށް ތަސްބީހަ ކިޔަތެވެ. އަދި އެކަލާނގެއަށް ހަމްދާއެކުގައި، ތަސްބީހަ ނުކިޔާ އެއްވެސް އެއްޗެއް ނުވެތެވެ. އެހެނެއްކަމަކު، ތިޔަބައިމީހުންނަކަށް އެތަކެތީގެ ތަސްބީހެއް ނުވިސްނެއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ހަލީމްވަންތަ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަސްކަލާނގެ ކަމުގައިވެއެވެ.","",""],["","","","وإذا قرأت القرآن جعلنا بينك وبين الذين لا يؤمنون بالآخرة حجابا مستورا","ކަލޭގެފާނު ގުރްއާން ކިޔަވައިވިދާޅުވާހިނދު، ކަލޭގެފާނާއި، އާޚިރަތް ދުވަހަށް އީމާން ނުވާމީހުންނާ ދެމެދު ނިވައިކުރަނިވި ފަރުދާއެއް، ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ.","",""],["","","","وجعلنا على قلوبهم أكنة أن يفقهوه وفي آذانهم وقرا وإذا ذكرت ربك في القرآن وحده ولوا على أدبارهم نفورا","އަދި އެއުރެންނަށް އެ ގުރްއާން ވިސްނުމަށް ހުރަސްއަޅާ ހުރަސްތަކެއް އެއުރެންގެ ހިތްތަކުގައި، ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ. އަދި އެއުރެންގެ ކަންފަތްތަކުގައި، ބީރުކަމެއް ލެއްވީމެވެ. އަދި ގުރްއާންގައި، ހަމައެކަނި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ނަންފުޅު ކަލޭގެފާނު ގެންނަވައިފިނަމަ، އެއުރެން ނުރުހުންތެރިވެ، ފުރަގަސްދީ އެނބުރި ހިނގައިދެތެވެ.","",""],["","","","نحن أعلم بما يستمعون به إذ يستمعون إليك وإذ هم نجوى إذ يقول الظالمون إن تتبعون إلا رجلا مسحورا","އެއުރެން ކަލޭގެފާނު ވިދާޅުވާ އެއްޗެއް އަޑުއަހާހިނދުގައްޔާއި، އަދި އެއުރެން ސިއްރުސައްލާކުރާހިނދު، އެއުރެން އެ އަޑުއަހާ އެއްޗެއް ތިމަންރަސްކަލާނގެ މޮޅަށް ދެނެވޮޑިގެންވަމެވެ. އަނިޔާވެރިވި މީހުން، އެހިނދު ބުނެތެވެ. ސިހުރު ޖެހިފައިވާ ފިރިހެނަކަށް މެނުވީ، ތިޔަބައިމީހުން ތަބައެއް ނުވަމުއެވެ.","",""],["","","","انظر كيف ضربوا لك الأمثال فضلوا فلا يستطيعون سبيلا","ކަލޭގެފާނާމެދު އެއުރެން މިސާލު ޖެހީ، ކޮންފަދައަކުންކަން ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާށެވެ! ފަހެ (އެކަމުގައި) އެއުރެން މަގުފުރެދިއްޖައޫއެވެ. ދެން އެއްވެސް މަގަކަށް، އެއުރެންނަށް ކުޅަދާނަވެގެންނެއް ނުވެތެވެ.","",""],["","","","وقالوا أإذا كنا عظاما ورفاتا أإنا لمبعوثون خلقا جديدا","އެއުރެން ބުނެފޫއެވެ. ތިމަންމެން ކަށިތަކަކަށްވެ، އަދި ފީވެ، ކުނޑިތަކަކަށް ވެއްޖެހިނދު، ހަމަކަށަވަރުން، އަލުން އުފެދުމަކަށް ފޮނުއްވާނޭ ބަޔަކު ކަމުގައި ތިމަންމެން ވޭހެއްޔެވެ؟","",""],["","","","قل كونوا حجارة أو حديدا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ހިލަކަމުގައި، ނުވަތަ ދަގަނޑު ކަމުގައި ވެބަލާށެވެ!","",""],["","","","أو خلقا مما يكبر في صدوركم فسيقولون من يعيدنا قل الذي فطركم أول مرة فسينغضون إليك رءوسهم ويقولون متى هو قل عسى أن يكون قريبا","ނުވަތަ ތިޔަބައިމީހުންގެ ހިތްތަކުގައި ބޮޑުކަން ލިބިގެންވާ ތަކެތީގެ ތެރެއިން އެހެންވެސް އެއްޗަކަށް ވެބަލާށެވެ! ފަހެ، އޭރުން އެއުރެން ބުނާނެތެވެ. ތިމަންމެން އަލުން ދިރުމަކަށް އިއާދަކުރާނީ ކާކުހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! އިސްވެދިޔަ މިސާލަކާނުލައި، ފުރަތަމަފަހަރުވެސް ތިޔަބައިމީހުން ހެއްދެވި ކަލާނގެއެވެ. ފަހެ، އެއުރެންގެ ބޯތައް ކަލޭގެފާނާ ދިމާޔަށް ހޫރައިލާނެތެވެ. އަދި ބުނާނެތެވެ. އެކަންވަނީ، ކޮންއިރަކުން ހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ވަރަށްއަވަހަށް އެކަންތައް ވުން ގާތްވެގެންވެތެވެ.","",""],["","","","يوم يدعوكم فتستجيبون بحمده وتظنون إن لبثتم إلا قليلا","އެކަލާނގެ ތިޔަބައިމީހުންނަށް ގޮވައިލައްވާ ދުވަހުއެވެ. ފަހެ، އެކަލާނގެއަށް ހަމްދާއެކު އެކަލާނގެ އަމުރު ފުޅަށް ތިޔަބައިމީހުން އިޖާބަދޭނޫއެވެ. އަދި ދާދިކުޑަހިނދުކޮޅަކަށް މެނުވީ (ދުނިޔޭގައި) ތިޔަބައިމީހުން ލަސްވެ ނުތިބޭކަމުގައި ތިޔަބައިމީހުން ހީކުރާނޫއެވެ.","",""],["","","","وقل لعبادي يقولوا التي هي أحسن إن الشيطان ينزغ بينهم إن الشيطان كان للإنسان عدوا مبينا","އެންމެ ރިވެތި ހެޔޮބަސްތަކުން ވާހަކަދައްކައި އުޅުމަށް، ތިމަންރަސްކަލާނގެ އަޅުންނަށް ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ޝައިތާނާ، އެއުރެންގެ މެދުގައި ފަސާދަ އުފައްދަތެވެ. ހަމަކަށަވަރުން، ޝައިތާނާއީ، އިންސާނާއަށް ފާޅުވެގެންހުރި އަދާވަތް ތެރިޔަކު ކަމުގައިވިއެވެ.","",""],["","","","ربكم أعلم بكم إن يشأ يرحمكم أو إن يشأ يعذبكم وما أرسلناك عليهم وكيلا","ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ތިޔަބައިމީހުން ދެނެވޮޑިގަތުން ބޮޑެވެ. އެކަލާނގެ އިރާދަކުރައްވާނަމަ، ތިޔަބައިމީހުންނަށް ރަހުމަތް ލައްވާނެތެވެ. ނުވަތަ އެކަލާނގެ އިރާދަކުރައްވާނަމަ، ތިޔަބައިމީހުންނަށް އަޒާބު ދެއްވާނެތެވެ. އަދި އެއުރެންގެ މައްޗަށް ހުންނެވި ވަކީލަކު ކަމުގައި، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ނުފޮނުއްވަމެވެ.","",""],["","","","وربك أعلم بمن في السماوات والأرض ولقد فضلنا بعض النبيين على بعض وآتينا داوود زبورا","އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، އުޑުތަކާއި، ބިމުގައިވާހާ ބަޔަކު ދެނެވޮޑިގަތުން ބޮޑެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، ބައެއް ނަބިއްޔުން އަނެއްބައި ނަބިއްޔުންގެ މައްޗަށް މާތްކުރެއްވީމެވެ. އަދި ދާވޫދުގެފާނަށް ތިމަންރަސްކަލާނގެ ޒަބޫރު ދެއްވީމެވެ.","",""],["","","","قل ادعوا الذين زعمتم من دونه فلا يملكون كشف الضر عنكم ولا تحويلا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަލާނގެ ފިޔަވައި، އިލާހު ންކަމަށް ތިޔަބައިމީހުން ހީކޮށްގެންއުޅޭ ފަރާތްތަކަށް ތިޔަބައިމީހުން ނިކަން ގޮވައިބަލާށެވެ! ފަހެ، ތިޔަބައިމީހުންގެ ކިބައިން ދަތިކަމެއް ފިލުވުމެއްވެސް، އަދި ބަދަލުކުރުމެއްވެސް، އެފަރާތްތަކަކަށް މަލަކަ ވެގެނެއް ނުވެތެވެ.","",""],["","","","أولئك الذين يدعون يبتغون إلى ربهم الوسيلة أيهم أقرب ويرجون رحمته ويخافون عذابه إن عذاب ربك كان محذورا","އިލާހު ންކަމަށް އެއުރެން ގޮވައިއުޅޭ ފަރާތްތައް، އެފަރާތްތަކުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ކުއްތަންވުމުގެ މަގު އެދެތެވެ. އެއުރެންކުރެ އެންމެ ގާތްކަންބޮޑީ، ކާކުތޯބަލައި އެކަމަށް އެދެތެވެ. އަދި އެކަލާނގެ ރަހުމަތަށް އެދެތެވެ. އަދި އެކަލާނގެ އަޒާބަށް ބިރުވެތިވޭމެއެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އަޒާބަކީ، އެއަށް ބިރުވެތިވެވޭކަމެއް ކަމުގައިވިއެވެ.","",""],["","","","وإن من قرية إلا نحن مهلكوها قبل يوم القيامة أو معذبوها عذابا شديدا كان ذلك في الكتاب مسطورا","ތިމަންރަސްކަލާނގެ ގިޔާމަތް ދުވަހުގެ ކުރިން ހަލާކު ނުކުރައްވާ އެއްވެސް (އަނިޔާވެރި) ރަށެއް ނުވެއެވެ. ނުވަތަ ގަދަވެގެންވާ އަޒާބަކުން އަޒާބު ނުދެއްވާ ރަށެއްވެސް ނުވެއެވެ. ފޮތުގައި (އެބަހީ: އައްލައުޙުލް މަޙްފޫޡުގައި) ލިޔުއްވާފައިވާ ކަމެއްކަމުގައި އެކަންތައްވިއެވެ.","",""],["","","","وما منعنا أن نرسل بالآيات إلا أن كذب بها الأولون وآتينا ثمود الناقة مبصرة فظلموا بها وما نرسل بالآيات إلا تخويفا","އިހުއުޅުނު މީހުން މުއުޖިޒާތައް ދޮގުކުޅަކަން މެނުވީ، ތިމަންރަސްކަލާނގެ މުއުޖިޒާތައް ފޮނުއްވުން މަނާކުރާކަމެއް ނެތެވެ. އަދި ފާޅުވެގެންވާ މުއުޖިޒާއެއްގެ ގޮތުގައި، ޘަމޫދު ބާގައި މީހުންނަށް ޖަމަލު ދެއްވީމެވެ. ދެން އެއުރެން އެއާމެދުގައި އަނިޔާވެރިވެގަތޫއެވެ. އަދި އިންޒާރެއް ކަމުގައި މެނުވީ ތިމަންރަސްކަލާނގެ މުއުޖިޒާތައް ނުފޮނުއްވަމެވެ.","",""],["","","","وإذ قلنا لك إن ربك أحاط بالناس وما جعلنا الرؤيا التي أريناك إلا فتنة للناس والشجرة الملعونة في القرآن ونخوفهم فما يزيدهم إلا طغيانا كبيرا","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ދެނެވޮޑިގަތުމާއި، ގުދުރަތް ތެރިކަން، މީސްތަކުން ވަށައިލާފައިވާކަމުގައި ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވިހިނދު، ހަނދުމަކުރައްވާށެވެ! އަދި ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ދެއްކެވި ދެއްކެވުމާއި، އަދި ގުރްއާންގައި ލައުނަތް ލައްވާފައިވާ ގަސް (އެއީ) މީސްތަކުންނަށް އިމްތިހާނެއް ކަމުގައި މެނުވީ، ތިމަންރަސްކަލާނގެ ނުލައްވަމެވެ. އަދި ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ބިރުދައްކަވައި އިންޒާރުކުރައްވަމެވެ. ފަހެ، ބޮޑުވެގެންވާ ދެކޮޅުވެރިކަން މެނުވީ، އެކަމުގެ ސަބަބުން، އެއުރެންނަށް އިތުރެއް ނުވެތެވެ.","",""],["","","","وإذ قلنا للملائكة اسجدوا لآدم فسجدوا إلا إبليس قال أأسجد لمن خلقت طينا","އާދަމުގެފާނަށް ތިޔަބައިމީހުން ސަޖިދަކުރާށޭ ތިމަންރަސްކަލާނގެ މަލާއިކަތުންނަށް ވަހީކުރެއްވިހިނދު ހަނދުމަކުރާށެވެ. ފަހެ، އިބްލީސް ފިޔަވައި، އެ މަލާއިކަތުން ސަޖިދަކުޅައޫއެވެ. އިބްލީސް ދެންނެވިއެވެ. އިބަރަސްކަލާނގެ މަށިން ހައްދަވާފައިވާ މީހަކަށް، ތިމަން ސަޖިދަކުރާނެތޯއެވެ؟","",""],["","","","قال أرأيتك هذا الذي كرمت علي لئن أخرتن إلى يوم القيامة لأحتنكن ذريته إلا قليلا","އެކަލޭގެ ދެންނެވިއެވެ. އިބަރަސްކަލާނގެ ތިމަންގެ މައްޗަށް މާތްކުރެއްވި، މި އިންސާނާއާމެދު އިބަރަސްކަލާނގެ އަންގަވައިދެއްވާނުތޯއެވެ؟ ގިޔާމަތަށް ދާނދެން، ތިމަން ލަހައްޓަވައި ދެއްވައިފިނަމަ، ހަމަކަށަވަރުން، ތިމަން އެ އިންސާނާގެ ދަރިފަސްކޮޅުގެ މަދުބަޔަކު މެނުވީ (މަގުފުރައްދައި) ނެތިކޮށްލާހުށީމެވެ.","",""],["","","","قال اذهب فمن تبعك منهم فإن جهنم جزاؤكم جزاء موفورا","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ކަލޭގެ ހިނގައިދާށެވެ! ފަހެ، އެއުރެންގެ ތެރެއިން، ކަލޭގެއަށް ތަބާ ވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ފުރިހަމަވެގެންވާ ޖަޒާއެއްގެގޮތުން، ތިޔަބައިމީހުން (އެންމެން) ގެ ޖަޒާއަކީ ނަރަކައެވެ.","",""],["","","","واستفزز من استطعت منهم بصوتك وأجلب عليهم بخيلك ورجلك وشاركهم في الأموال والأولاد وعدهم وما يعدهم الشيطان إلا غرورا","އަދި އެއުރެންގެ ތެރެއިން، ކަލޭގެޔަށް ކުޅަދާނަވީ ބަޔަކު، ކަލޭގެ އަޑުން ބިރުގަންނަވައި ހެއްލުންތެރިކުރާށެވެ! އަދި ކަލޭގެ ސަވާރުންތަކާއި، ފައިމަގުގައިވާ މީހުންތައް މެދުވެރިކޮށް، އެއުރެންގެމައްޗަށް ބާރުހިންގާށެވެ! އަދި މުދާތަކާއި، ދަރިފަސްކޮޅުތަކުގައި އެއުރެން ބައިވެރިކުރާށެވެ! އަދި އެއުރެންނަށް ވައުދުކުރާށެވެ! ހެއްލުންތެރިކަމެއްމެނުވީ، ޝައިތާނާ އެއުރެންނަކަށް ވައުދެއް ނުކުރެތެވެ.","",""],["","","","إن عبادي ليس لك عليهم سلطان وكفى بربك وكيلا","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އަޅުންގެ މައްޗަށް ކަލޭގެއަކަށް ބާރެއް ލިބިގެނެއް ނުވެއެވެ. ވަކީލަކު ކަމުގައި، ކަލޭގެ ވެރިރަސްކަލާނގެ ފުދެއެވެ.","",""],["","","","ربكم الذي يزجي لكم الفلك في البحر لتبتغوا من فضله إنه كان بكم رحيما","ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއީ، ތިޔަބައިމީހުންނަށްޓަކައި، ކަނޑުގައި އުޅަނދުތައް ދުވާގޮތް މެދުވެރިކޮށްދެއްވި ކަލާނގެއެވެ. (އެއީ) އެކަލާނގެ ފަޟްލު ވަންތަކަމުގެތެރެއިން (ކަންކަމަށް) ތިޔަބައިމީހުން އެދިއުޅުމަށެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށް ރަޙީމްވަންތަ ކަލަކު ކަމުގައި، އެކަލާނގެ ވޮޑިގެންވެއެވެ.","",""],["","","","وإذا مسكم الضر في البحر ضل من تدعون إلا إياه فلما نجاكم إلى البر أعرضتم وكان الإنسان كفورا","އަދި ކަނޑުމަތީގައި ތިޔަބައިމީހުންނަށް ދަތިޙާލު ޖެހިއްޖެހިނދަކު، ތިޔަބައިމީހުން އެހީއަށްއެދި ގޮވާ ފަރާތްތަކުގެ ތެރެއިން، އެކަލާނގެ ފިޔަވައި އެހެންހުރިހާ ފަރާތެއް ގެއްލިދެއެވެ. ފަހެ، އެކަލާނގެ ތިޔަބައިމީހުން ސަލާމަތްކުރައްވައި، އެއްގަމަށް ގެންނަވައިފިހިނދު (އެކަލާނގެ ފިޔަވައި) ތިޔަބައިމީހުން ފުރަގަސްދީ ހިނގައިދެއެވެ. ނިއުމަތަށް އިންކާރުކޮށް، ދެކޮޅުވެރިވާ މީހަކު ކަމުގައި އިންސާނާވިއެވެ.","",""],["","","","أفأمنتم أن يخسف بكم جانب البر أو يرسل عليكم حاصبا ثم لا تجدوا لكم وكيلا","ފަހެ، އެކަލާނގެ ތިޔަބައިމީހުންނާއެކު، ހިކިފަސްތަނުގެ ބައެއް ގަންބަވައިގެންފާނެކަމާމެދު، ނުވަތަ ތިޔަބައިމީހުންގެ މައްޗަށް ކުދި ހިލައިގެ ވާރޭ ފޮނުއްވައިފާނޭ ކަމާމެދު، ތިޔަބައިމީހުން އަމާންކަން ލިބިގަތީހެއްޔެވެ؟ ދެން ތިޔަބައިމީހުން ރައްކާތެރިކުރާނޭ މީހަކު ތިޔަބައިމީހުންނަކަށް ނުފެންނާނެތެވެ.","",""],["","","","أم أمنتم أن يعيدكم فيه تارة أخرى فيرسل عليكم قاصفا من الريح فيغرقكم بما كفرتم ثم لا تجدوا لكم علينا به تبيعا","ނުވަތަ ތިޔަބައިމީހުން އަލުން އެ ކަނޑުގެ ތެރެއަށް ދެވަނަފަހަރަށް ފޮނުއްވައި، ތިޔަބައިމީހުންގެ މައްޗަށް، ވައިގެ ގަދަރޯޅިއެއް ފޮނުއްވައި، ދެން ތިޔަބައިމީހުން ކާފިރު ވީކަމުގެ ސަބަބުން، ތިޔަބައިމީހުން ޣަރަގުކުރައްވައިފާނެކަމާމެދު، ތިޔަބައިމީހުން އަމާންކަން ލިބިގަތީހެއްޔެވެ؟ ދެން އެކަމުގެ ސަބަބުން، ތިމަންރަސްކަލާނގެއާ ދެކޮޅަށް، ނަސްރުވެރިވާނެ ފަރާތެއް ތިޔަބައިމީހުންނަކަށް ނުފެންނާނެތެވެ.","",""],["","","","ولقد كرمنا بني آدم وحملناهم في البر والبحر ورزقناهم من الطيبات وفضلناهم على كثير ممن خلقنا تفضيلا","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އާދަމުގެދަރިން މާތްކުރެއްވީމެވެ. އަދި އެއުރެން އެއްގަމާއި ކަނޑުގައި، އުފުއްލެވީމެވެ. އަދި އެއުރެންނަށް ރަނގަޅު ތަކެތިން ރިޒްގު ދެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ ހެއްދެވި ތަކެތީގެ ތެރެއިން، ގިނަ ތަކެތީގެ މައްޗަށް އެއުރެން މަތިވެރި ދަރަޖައަކަށް މާތްކުރެއްވީމެވެ.","",""],["","","","يوم ندعو كل أناس بإمامهم فمن أوتي كتابه بيمينه فأولئك يقرءون كتابهم ولا يظلمون فتيلا","ކޮންމެ ބަޔަކަށްމެ، އެބަޔެއްގެ އިމާމުގެ ނަމުން ތިމަންރަސްކަލާނގެ ގޮވައިލައްވާނޭ ދުވަސް ހަނދުމަކުރާށެވެ! ފަހެ، އެމީހެއްގެ ފަތް އެމީހެއްގެ ކަނާތަށް ލިބިއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެން، އެއުރެންގެ ފަތް ކިޔާނެތެވެ. އަދި އެއުރެންނަށް ކިތަންމެ ކުޑަ މިންވަރަކުންވިޔަސް، ބޭއިންސާފެއް ނުކުރައްވާނެތެވެ.","",""],["","","","ومن كان في هذه أعمى فهو في الآخرة أعمى وأضل سبيلا","އަދި މިދުނިޔޭގައި (ހައްގު ގޮތް ފިޔަވައި) ކަނުމީހަކު، އާޚިރަތް ދުވަހުގައިވެސް ވާނީ، ކަނުމީހެއް ކަމުގައެވެ. އޭނާ ވާހުށީ، މަގު ގެއްލިފައިވާ މީހަކު ކަމުގައެވެ.","",""],["","","","وإن كادوا ليفتنونك عن الذي أوحينا إليك لتفتري علينا غيره وإذا لاتخذوك خليلا","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނަށް އިއްވެވި ވަހީ އިން ކަލޭގެފާނު އެއްކިބާކުރުމަށް، އެއުރެން ގާތްކުޅައޫއެވެ. (އެއީ) ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ވަހީ ނުކުރައްވާ އެއްޗެއް، ކަލޭގެފާނު ހައްދަވައިގެން ތިމަންރަސްކަލާނގެއަށް ނިސްބަތްކުރެއްވުމަށް (އެދި އެކަމަށް) ޓަކައެވެ. (އެކަން އެގޮތަށް ކުރެއްވިނަމަ) އޭރުން ހަމަކަށަވަރުން، އެއުރެން، ކަލޭގެފާނީ މިތުރަކު ކަމުގައި ހެދީހެވެ.","",""],["","","","ولولا أن ثبتناك لقد كدت تركن إليهم شيئا قليلا","އަދި ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ގަދަކަންދެއްވައި، ޘާބިތު ކޮށް ނުދެއްވިނަމަ، ހަމަކަށަވަރުން، ކަލޭގެފާނު އެއުރެންނަށް ހިސާބަކަށް ލެނބިވަޑައިގަތުން ގާތްވީހެވެ.","",""],["","","","إذا لأذقناك ضعف الحياة وضعف الممات ثم لا تجد لك علينا نصيرا","އޭރުން، ދުނިޔަވީ ހަޔާތްގެ (އުގޫބާތްގެ) ދެބަޔާއި، އާޚިރަތްގެ (އުގޫބާތްގެ) ދެބައިން ހަމަކަށަވަރުން، ކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ ރަހަ ދެއްކެވީމުހެވެ. ދެން ތިމަންރަސްކަލާގެ (އަޒާބު) އާ ދެކޮޅަށް، ކަލޭގެފާނަށް ނަސްރު ދޭނެ، އެއްވެސްމީހަކު، ކަލޭގެފާނަކަށް ފެނިވަޑައެއް ނުގަންނަވާނެތެވެ.","",""],["","","","وإن كادوا ليستفزونك من الأرض ليخرجوك منها وإذا لا يلبثون خلافك إلا قليلا","އަދި އެއުރެން ހަމަކަށަވަރުން، ކަލޭގެފާނަށް (އަދާވަތް ތެރިވެ) އުނދަގޫކޮށް، ކަލޭގެފާނު (މައްކާގެ) ބިމުން ބޭރުކޮށްލުމަށް ގާތްކުޅައޫއެވެ. (އެހެންވެއްޖެނަމަ) އޭރުން، ކުޑަވަގުތުކޮޅަކަށް މެނުވީ، ކަލޭގެފާނަށްފަހު އެއުރެންނަކަށް (އެތާކު) ނުތިބެވޭނެތެވެ.","",""],["","","","سنة من قد أرسلنا قبلك من رسلنا ولا تجد لسنتنا تحويلا","(އެއީ) ތިމަންރަސްކަލާނގެ ރަސޫލުންގެ ތެރެއިން ކަލޭގެފާނުގެ ކުރިން ތިމަންރަސްކަލާނގެ ފޮނުއްވި ރަސޫލުންނާމެދު، ކަންތައް ހިންގެވިގޮތެވެ. އަދި ތިމަންރަސްކަލާނގެ ކަންހިންގަވާގޮތް، އެހެންފަރާތަކަށް އަނބުރައިލެވޭތީވެސް ކަލޭގެފާނަކަށް ފެނިވަޑައެއް ނުގަންނަވާނެތެވެ.","",""],["","","","أقم الصلاة لدلوك الشمس إلى غسق الليل وقرآن الفجر إن قرآن الفجر كان مشهودا","އިރު މެދުން ފިލުމުން، ރޭގަނޑުގެ އަނދިރިކަމާ ހަމަޔަށް، ކަލޭގެފާނު ނަމާދު ގާއިމުކުރައްވާށެވެ! (އެބަހީ: މެންދުރު ނަމާދާއި، ޢަޞްރު ނަމާދާއި، މަޣްރިބު ނަމާދާއި، ޢިޝާ ނަމާދު ގާއިމުކުރައްވާށެވެ!) އަދި ފަތިސްނަމާދު ކުރައްވާށެވެ! ހަމަކަށަވަރުން، ފަތިސްނަމާދަކީ، (ރޭގަނޑުގެ މަލާއިކަތްނާއި ދުވާލުގެ މަލާއިކަތުންގެ ފަރާތްޕުޅުން) ހެކިލިބިގެންވާ ނަމާދެއް ކަމުގައިވިއެވެ.","",""],["","","","ومن الليل فتهجد به نافلة لك عسى أن يبعثك ربك مقاما محمودا","އަދި (ފަރުޟު ފަސްނަމާދުގެ އިތުރަށް) ކަލޭގެފާނަށް ހާއްސަ ނަމާދެއްގެ ގޮތުގައި، ރޭގަނޑުގެ ބައެއްގައި އެ ގުރްއާން ކިޔަވައިވިދާޅުވެ، ތަހައްޖުދު ނަމާދު ކުރައްވާށެވެ! އެކަމުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، ހަމްދު ލިބިގެންވާ މަގާމަކަށް ކަލޭގެފާނު ފޮނުއްވައިފާހުށްޓެވެ!","",""],["","","","وقل رب أدخلني مدخل صدق وأخرجني مخرج صدق واجعل لي من لدنك سلطانا نصيرا","އަދި ކަލޭގެފާނު ވިދާޅުވާށެވެ! އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! އިބަރަސްކަލާނގެ ރުހިވޮޑިގެންވާ ގޮތުގައި ތިމަންއަޅާ ވައްދަވާނދޭވެ! އަދި އިބަރަސްކަލާނގެ ރުހިވޮޑިގެންވާ ގޮތުގައި މިއަޅާ ނެރުއްވާނދޭވެ! އަދި ނަސްރު ދެނިވި ބާރެއް އިބަރަސްކަލާނގެ ހަޒުރަތުން މިއަޅާއަށް ލައްވާނދޭވެ!","",""],["","","","وقل جاء الحق وزهق الباطل إن الباطل كان زهوقا","އަދި ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހައްގު ތެދުގޮތް އަތުވެއްޖެއެވެ. އަދި ބާތިލު ގޮތް ނެތި ފިލައިހިނގައްޖެއެވެ. ހަމަކަށަވަރުން، ބާތިލަކީ، ނެތިވެ ފިލައިދަނިވި އެއްޗެއްކަމުގައިވިއެވެ.","",""],["","","","وننزل من القرآن ما هو شفاء ورحمة للمؤمنين ولا يزيد الظالمين إلا خسارا","ތިމަންރަސްކަލާނގެ ގުރްއާނުން މުއުމިނުންނަށް ރަހުމަތާއި، ޝިފާކަމުގައިވާ ތަކެތި ބާވައިލައްވަމެވެ. އަދި އެ ގުރްއާނުން، އަނިޔާވެރިވި މީހުންނަށް ގެއްލުމެއް މެނުވީ އިތުރެއް ނުވާހުށްޓެވެ.","",""],["","","","وإذا أنعمنا على الإنسان أعرض ونأى بجانبه وإذا مسه الشر كان يئوسا","އަދި އިންސާނާއަށް، ތިމަންރަސްކަލާނގެ ނިއުމަތް ދެއްވައިފިނަމަ، އަނެއްފަރާތަށް އެނބުރި ބޮޑާވެގަނެތެވެ. އަދި އޭނާއަށް ނުބައިކަމެއް ޖެހިއްޖެނަމަ، (އެކަލާނގެ ރަހުމަތުން) އުންމީދު ކަނޑައިލާ މީހަކަށް ވެދެތެވެ.","",""],["","","","قل كل يعمل على شاكلته فربكم أعلم بمن هو أهدى سبيلا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ކޮންމެ މީހަކުމެ، ޢަމަލުކުރަމުންދަނީ އެމީހެއްގެ ގޮތަށެވެ. ފަހެ، އެންމެބޮޑަށް ތެދުމަގު ލިބިފައިވަނީ ކާކުކަން މޮޅަށް ދެނެވޮޑިގެންވަނީ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["","","","ويسألونك عن الروح قل الروح من أمر ربي وما أوتيتم من العلم إلا قليلا","ފުރާނައިގެ ވާހަކައިން އެއުރެން ކަލޭގެފާނާ ސުވާލުކުރެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ފުރާނައަކީ (ހަމައެކަނި) ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ދެނެވޮޑިގަތުމުގެ ތެރެއިންވާ އެއްޗެކެވެ. އަދި ތިޔަބައިމީހުންނަށް (އެބަހީ: އިންސާނުންނަށް) އިލްމުގެ ތެރެއިން ވަރަށްކުޑަ މިންވަރެއް މެނުވީ ދެއްވައިފައެއް ނުވެއެވެ.","",""],["","","","ولئن شئنا لنذهبن بالذي أوحينا إليك ثم لا تجد لك به علينا وكيلا","އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވައިފިނަމަ، ކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވި ތަކެތި ގެންދަވައިފާހުށީމެވެ. ދެން އެކަމާމެދު ތިމަންރަސްކަލާނގެއާ ދެކޮޅަށް ކަލޭގެފާނަށް އެހީތެރިވާނޭ މީހަކު، ކަލޭގެފާނަކަށް ފެނިވަޑައެއް ނުގަންނަވާނެތެވެ.","",""],["","","","إلا رحمة من ربك إن فضله كان عليك كبيرا","ނަމަވެސް، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ރަހުމަތްފުޅުން (އެކަމެއް ނުކުރައްވަތެވެ.) ހަމަކަށަވަރުން، އެކަލާނގެ ފަޟްލު ވަންތަކަން، ކަލޭގެފާނުގެ މައްޗަށް ބޮޑުވެގެންވެއެވެ.","",""],["","","","قل لئن اجتمعت الإنس والجن على أن يأتوا بمثل هذا القرآن لا يأتون بمثله ولو كان بعضهم لبعض ظهيرا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، މި ގުރްއާނާ އެއްފަދަ އެއްޗެއް ގެނައުމަށް އިންސީންނާއި، ޖިންނީން އެއްވިނަމަވެސް، އެއާ އެއްފަދަ އެއްޗެއް އެއުރެންނަކަށް ނުގެނެވޭނެތެވެ. އެއުރެންގެ އެއްބަޔަކު އަނެއްބަޔަކަށް ވާގިވެރިން ކަމުގައި ވީނަމަވެސްމެއެވެ.","",""],["","","","ولقد صرفنا للناس في هذا القرآن من كل مثل فأبى أكثر الناس إلا كفورا","ހަމަކަށަވަރުން، މި ގުރްއާންގައި ތިމަންރަސްކަލާނގެ މީސްތަކުންނަށް ހުރިހާ ބާވަތަކުން މިސާލު ބަޔާންކުރެއްވީމެވެ. ދެންވެސް މީސްތަކުންކުރެ ގިނަމީހުން، ދެކޮޅުވެރިވެ، ކާފިރު ވުން މެނުވީ ގަބޫލެއް ނުކުރޫއެވެ.","",""],["","","","وقالوا لن نؤمن لك حتى تفجر لنا من الأرض ينبوعا","އަދި އެއުރެން ބުނެފޫއެވެ. ކަލޭގެފާނު (މައްކާގެ) ބިމުން ތިމަންމެންނަށް ފެންއާރެއް ހިންގަވައިދެއްވައިފުމަށް ދާނދެން ކަލޭގެފާނަކަށް ތިމަންމެން އީމާނެއް ނުވާނޫއެވެ.","",""],["","","","أو تكون لك جنة من نخيل وعنب فتفجر الأنهار خلالها تفجيرا","ނުވަތަ ކަލޭގެފާނަށް، ކަދުރު ރުކާއި، މޭބިސްކަދުރުގެ ބަގީޗާއެއްއޮވެ، އޭގެ މެދުން ގިނަގުނަ ކޯރުތައް ހިންގަވައިދެއްވައިފުމަށް ދާނދެނެވެ.","",""],["","","","أو تسقط السماء كما زعمت علينا كسفا أو تأتي بالله والملائكة قبيلا","ނުވަތަ ކަލޭގެފާނު ހީފުޅުކުރައްވާ ފަދައިން، ތިމަންމެންގެ މައްޗަށް އެތިއެތިގަނޑަށް އުޑު ވައްޓަވައިލައްވައިފުމަށް ދާނދެން، ނުވަތަ ﷲއާއި މަލާއިކަތުން (ތިމަންމެންނަށް) ފެންނާނެހެން ކުރިމައްޗަށް ގެނެސްދެއްވައިފުމަށް ދާނދެނެވެ.","",""],["","","","أو يكون لك بيت من زخرف أو ترقى في السماء ولن نؤمن لرقيك حتى تنزل علينا كتابا نقرؤه قل سبحان ربي هل كنت إلا بشرا رسولا","ނުވަތަ ކަލޭގެފާނަށް ރަނުން ގެއެއް ހުރެ، ނުވަތަ ކަލޭގެފާނު އުޑަށް އަރައިވަޑައިގެންފުމަށް ދާނދެނެވެ. އަދި ތިމަންމެން ކިޔަވާނޭ ފޮތެއް ތިމަންމެންނަށް ބާލުއްވައިދެއްވައިފުމަށް ދާނދެން، ކަލޭގެފާނު (އުޑަށް) އަރައިވަޑައިގެންނެވިކަމަކަށް، ތިމަންމެން އީމާނެއް ނުވާނޫއެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އަޅުގެ ވެރިރަސްކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! ތިމަންކަލޭގެފާނަކީ، ރަސޫލަކު ކަމުގައިވާ އާދަމުގެދަރިޔަކު ކަމުގައި މެނުވީ ނުވަމެވެ.","",""],["","","","وما منع الناس أن يؤمنوا إذ جاءهم الهدى إلا أن قالوا أبعث الله بشرا رسولا","މީސްތަކުންގެ ގާތަށް ތެދުމަގު އައިހިނދު، ﷲ، ރަސޫލަކު ކަމުގައި އާދަމުގެދަރިޔަކު ފޮނުއްވީހޭ، އެއުރެން ބުނާ ބުނުން މެނުވީ، އެއުރެން އީމާން ވުން މަނައެއް ނުކުރެތެވެ.","",""],["","","","قل لو كان في الأرض ملائكة يمشون مطمئنين لنزلنا عليهم من السماء ملكا رسولا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ބިމުގައި ހިންގަވައި، ދިރިއުޅުއްވަނީ މަލާއިކަތުން ކަމުގައިވީނަމަ، އެބޭކަލުންގެ ގާތަށް ރަސޫލަކު ކަމުގައި ތިމަންރަސްކަލާނގެ އުޑުން މަލާއިކަތަކު ބާވައިލެއްވީމުހެވެ.","",""],["","","","قل كفى بالله شهيدا بيني وبينكم إنه كان بعباده خبيرا بصيرا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނާއި، ތިޔަބައިމީހުންނާ ދެމެދުގައި ހެތްކަކަށް ﷲ ފުދެއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، އެކަލާނގެ އަޅުތަކުންގެ ޚަބަރުތައް މޮޅަށްދެނެވޮޑިގެންވާ، މޮޅަށްބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެ ކަމުގައިވެއެވެ.","",""],["","","","ومن يهد الله فهو المهتد ومن يضلل فلن تجد لهم أولياء من دونه ونحشرهم يوم القيامة على وجوههم عميا وبكما وصما مأواهم جهنم كلما خبت زدناهم سعيرا","ﷲ ތެދުމަގު ދެއްކެވި މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކީ، ތެދުމަގު ލިބިފައިވާ މީހެކެވެ. އަދި އެކަލާނގެ މަގުފުރައްދަވައިފި މީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންނަށް އެކަލާނގެ ފިޔަވައި އެހީތެރިވާނޭ ބަޔަކު ކަލޭގެފާނަކަށް ފެނިވަޑައެއް ނުގަންނަވާނެތެވެ. އަދި ގިޔާމަތް ދުވަހުން ތިމަންރަސްކަލާނގެ އެއުރެން މޫނުވަތަށް މަހުޝަރަށް ފޮނުއްވާހުށީމެވެ. ކަނު، މަންމަން، ބީރުބަޔަކު ކަމުގައެވެ. އެއުރެން ތިބެނިވިތަނަކީ ނަރަކައެވެ. އެ ނަރަކައިގެ ހުޅުގަނޑު ކުޑަވާ ކޮންމެފަހަރަކު، އެއުރެންނަށް އެ ހުޅުގަނޑު އަނދައިގަތުން އިތުރުކުރައްވަމެވެ.","",""],["","","","ذلك جزاؤهم بأنهم كفروا بآياتنا وقالوا أإذا كنا عظاما ورفاتا أإنا لمبعوثون خلقا جديدا","އެއީ ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް އެއުރެން ކާފިރުވި ކަމަށްޓަކައި އެއުރެންނަށް ހުރި ޖަޒާއެވެ. އަދި އެއުރެން ބުނޫއެވެ. ތިމަންމެން ކަށިތަކަކަށްވެ، އަދި ފީވެ، ކުނޑިތަކަކަށްވެއްޖެހިނދު، ހަމަކަށަވަރުން، އަލުން އުފެދުމަކަށް ފޮނުއްވާނޭ ބަޔަކުކަމުގައި ތިމަންމެން ވޭހެއްޔެވެ؟","",""],["","","","أولم يروا أن الله الذي خلق السماوات والأرض قادر على أن يخلق مثلهم وجعل لهم أجلا لا ريب فيه فأبى الظالمون إلا كفورا","އުޑުތަކާއި، ބިން ހެއްދެވި ﷲ، އެއުރެންފަދަ ބަޔަކު ހެއްދެވުމަށް ކުޅަދުންވަންތަކަން، އެއުރެންނަކަށް ނޭނގޭހެއްޔެވެ؟ އެކަލާނގެ އެއުރެންނަށްވަނީ، ވަކިމުއްދަތެއް ކަނޑައަޅުއްވާފައެވެ. އެއާމެދަކު ޝައްކެއްނެތެވެ. ފަހެ، އެ އަނިޔާވެރިވެގަތް މީހުން ދެކޮޅުވެރިކަމާއި، ކާފިރު ކަން މެނުވީ ގަބޫލެއް ނުކުރެތެވެ.","",""],["","","","قل لو أنتم تملكون خزائن رحمة ربي إذا لأمسكتم خشية الإنفاق وكان الإنسان قتورا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންނަށް ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ރަހުމަތްގެ ޚަޒާނާތައް މިލްކުވީނަމަ، ދެންއެހާރުން، ހޭދަކޮށް، ހުސްވެދާނެކަމަށް ބިރުން ތިޔަބައިމީހުން (ޚަރަދު ނުކޮށް) ހިފެހެއްޓީސްކަން ކަށަވަރެވެ. އަދި ދަހިވެތި މީހަކު ކަމުގައި އިންސާނާ ވިއެވެ.","",""],["","","","ولقد آتينا موسى تسع آيات بينات فاسأل بني إسرائيل إذ جاءهم فقال له فرعون إني لأظنك يا موسى مسحورا","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ފާޅުވެ ބަޔާންވެގެންވާ ނުވަ މުއުޖިޒާއެއް، މޫސާގެފާނަށް ދެއްވީމެވެ. ފަހެ، އެކަލޭގެފާނު އެއުރެންގެ ގާތަށް ވަޑައިގަތްހިނދު (ކަންހިނގިގޮތް) އިސްރާއީލުގެދަރިންކުރެން ކަލޭގެފާނު އައްސަވައި ބައްލަވާށެވެ! ފަހެ، ފިރްޢައުނު، އެކަލޭގެފާނަށް ދެންނެވިއެވެ. އޭ މޫސާގެފާނެވެ! ހަމަކަށަވަރުން، އަހުރެންނަށް ހީވަނީ، ކަލޭގެފާނަށް ސިހުރު ޖެހިފައިވާ ކަމަށެވެ.","",""],["","","","قال لقد علمت ما أنزل هؤلاء إلا رب السماوات والأرض بصائر وإني لأظنك يا فرعون مثبورا","އެކަލޭގެފާނު ވިދާޅުވިއެވެ! ހަމަކަށަވަރުން، ބަޔާންވެގެންވާ އިބްރަތް ތަކެއް ކަމުގައި މި މުއުޖިޒާތައް ބާވައިލެއްވީ، އުޑުތަކާއި، ބިމުގެ ވެރިރަސްކަލާނގެ ފިޔަވައި އެހެންފަރާތެއް ނޫންކަން ކަލޭ ރަނގަޅަށް ދަންނާނޫއެވެ. އޭ ފިރްޢައުނެވެ! ހަމަކަށަވަރުން، އަހުރެންނަށް ޔަގީން ވަނީ، ކަލެއަކީ ގެއްލި ހަލާކުވެފައިވާ މީހެއް ކަމުގައެވެ.","",""],["","","","فأراد أن يستفزهم من الأرض فأغرقناه ومن معه جميعا","ފަހެ، އޭނާ ގަސްދުކުރީ އެއުރެން (މިސްރުގެ) ބިމުން ބޭރުކޮށްލުމަށެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ އޭނާއާއި، އޭނާއާއެކުގައިވާ އެންމެން ޣަރަގުކުރެއްވީމެވެ.","",""],["","","","وقلنا من بعده لبني إسرائيل اسكنوا الأرض فإذا جاء وعد الآخرة جئنا بكم لفيفا","އަދި އެއަށްފަހުގައި، ތިމަންރަސްކަލާނގެ އިސްރާއީލުގެދަރިންނަށް އެންގެވީމެވެ. ތިޔަބައިމީހުން އެ ބިމުގައި ވަޒަންވެރިވެ އުޅޭށެވެ! ދެން ގިޔާމަތް ދުވަހުގެ ވައުދު އަތުވެއްޖެނަމަ، ތިޔަބައިމީހުން އެންމެން އެކުގައިވާ ޙާލު، ޙާޒިރުުކުރައްވާ ހުށީމެވެ.","",""],["","","","وبالحق أنزلناه وبالحق نزل وما أرسلناك إلا مبشرا ونذيرا","ތިމަންރަސްކަލާނގެ އެ ގުރްއާން ބާވައިލެއްވީ، ހައްގާ އެކުގައެވެ. އަދި އެ ގުރްއާން އައީ، ހައްގު ގޮތުގައެވެ. އަދި އުފާވެރި ޚަބަރު ދެއްވާ ބޭކަލަކު ކަމުގައްޔާއި، އިންޒާރުކުރައްވާ ބޭކަލަކު ކަމުގައި މެނުވީ، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ނުފޮނުއްވަމެވެ.","",""],["","","","وقرآنا فرقناه لتقرأه على الناس على مكث ونزلناه تنزيلا","އަދި ކަލޭގެފާނު މީސްތަކުންނަށް (ވިސްނޭނެހެން) ލަސްލަހުން ކިޔަވައި ވިދާޅުވެދެއްވުމަށްޓަކައި، ވަކިވަކިކޮށް ތިމަންރަސްކަލާނގެ އެ ގުރްއާން ބާވައިލެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އެ ގުރްއާން އެކިފަހަރުމަތިން ބާވައިލެއްވީމެވެ.","",""],["","","","قل آمنوا به أو لا تؤمنوا إن الذين أوتوا العلم من قبله إذا يتلى عليهم يخرون للأذقان سجدا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން، އެ ގުރްއާނަށް އީމާން ވާށެވެ! ނުވަތަ އީމާން ނުވާށެވެ! ހަމަކަށަވަރުން، އޭގެކުރިން އިލްމު ލިބިގެންވާ މީހުންނަށް އެ ގުރްއާން ކިޔަވައިދެއްވާހިނދު، އެއުރެން ސަޖިދަކުރާ ޙާލު، މޫނުވަތަށް ތިރިވެއެވެ.","",""],["","","","ويقولون سبحان ربنا إن كان وعد ربنا لمفعولا","އަދި އެއުރެން ބުނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާނގެ ހުސްތާހިރުވަންތަ ކަމާއެވެ! ހަމަކަށަވަރުން، ތިމަންމެންގެ ވެރިރަސްކަލާނގެ ވައުދު ފުޅާ އެއްގޮތަށް ކަންތައް ވާހުށިކަން ކަށަވަރެވެ.","",""],["","","","ويخرون للأذقان يبكون ويزيدهم خشوعا","އަދި އެއުރެން ރޮމުން މޫނުވަތަށް ސަޖިދަށް ތިރިވެއެވެ. އަދި އެ ގުރްއާން، އެއުރެންނަށް މަޑުމޮޅިކަން އިތުރުކޮށްދެއެވެ.","",""],["","","","قل ادعوا الله أو ادعوا الرحمن أيا ما تدعوا فله الأسماء الحسنى ولا تجهر بصلاتك ولا تخافت بها وابتغ بين ذلك سبيلا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން، ﷲގެ އިސްމުފުޅުން ދުއާކުރާށެވެ! ނުވަތަ ރަޙްމާންގެ އިސްމުފުޅުން ދުއާކުރާށެވެ! ތިޔަބައިމީހުން (އެކަލާނގެ އިސްމު ފުޅުތަކުން) ކޮންމެ އިސްމު ފުޅަކުން ދުއާކުރިޔަސް (ހަމަހަމައެވެ.) ފަހެ، އެކަލާނގެއަށް الأسماء الحسنى (އޭ ކިއުނު އިސްމުފުޅުތައް) ވެއެވެ. އަދި ކަލޭގެފާނު ނަމާދުގައި މާއަޑުހަރުކޮށް ކިޔަވައިވިދާޅުނުވާށެވެ! އަދި އެ ނަމާދުގައި މާ މަޑުންވެސް ކިޔަވައިވިދާޅުނުވާށެވެ! އަދި އެދޭތެރޭގެ މެދުމިން މަގެއް ކަލޭގެފާނު ގަސްދުކުރައްވާށެވެ!","",""],["","","","وقل الحمد لله الذي لم يتخذ ولدا ولم يكن له شريك في الملك ولم يكن له ولي من الذل وكبره تكبيرا","އަދި ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމްދު ހުރީ ﷲއަށެވެ. އެކަލާނގެއީ، ދަރިކަލަކު ނުހިއްޕަވާ ރަސްކަލާނގެއެވެ. އަދި ވެރިކަމުގައި އެކަލާނގެއަށް އެއްވެސް ބައިވެރިޔަކު ނުވެއެވެ. އަދި ނިކަމެތިކަމުން ސަލާމަތްކުރާނޭ ރައްކާތެރިޔަކު އެކަލާނގެއަކަށް ނުމެވޭމެއެވެ. އަދި ކަލޭގެފާނު ގިނަގިނައިން އެކަލާނގެއަށް ތަކްބީރު ވިދާޅުވާށެވެ!","",""],["","","","بسم الله الرحمن الرحيم الحمد لله الذي أنزل على عبده الكتاب ولم يجعل له عوجا","ހަމްދު ހުރީ ﷲއަށެވެ. އެކަލާނގެއީ، އެކަލާނގެ އަޅާއަށް ފޮތް ބާވައިލެއްވި ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެ އެ ފޮތުގައި، އެއްވެސް ގުދުކަމެއް (ނުސީދާކަމެއް) ނުލައްވަތެވެ.","",""],["","","","قيما لينذر بأسا شديدا من لدنه ويبشر المؤمنين الذين يعملون الصالحات أن لهم أجرا حسنا","(އެ ފޮތް ބާވައިލެއްވީ) ސީދާވެގެންވާ ފޮތެއްކަމުގައެވެ. އެކަލާނގެ ހަޒުރަތުން (ކާފިރުންނަށް) ހުރި ގަދަފަދަ އަޒާބެއްގެ ވާހަކައިން އިންޒާރުކުރެއްވުމަށެވެ. އަދި ސާލިހު ޢަމަލުތައްކުރާ މުއުމިނުންނަށް، ހެޔޮވެގެންވާ ދަރުމަހުރިކަމުގެ އުފާވެރި ޚަބަރު ދެއްވުމަށެވެ.","",""],["","","","ماكثين فيه أبدا","އެ ދަރުމައިގައި، އެއުރެން އަބަދަށް ދެމިތިބެނިވި ގޮތުގައެވެ.","",""],["","","","وينذر الذين قالوا اتخذ الله ولدا","އަދި ﷲ، ދަރިކަލަކު ހިއްޕެވިކަމަށް ބުނިމީހުންނަށް އިންޒާރުކުރެއްވުމަށްޓަކައެވެ.","",""],["","","","ما لهم به من علم ولا لآبائهم كبرت كلمة تخرج من أفواههم إن يقولون إلا كذبا","އެއުރެންނަކަށްވެސް، އަދި އެއުރެންގެ ކާބަފައިންނަކަށްވެސް (އެއުރެން އެބުނާ ބަހާމެދު) އެއްވެސް އިލްމެއް ލިބިފައެއް ނުވެއެވެ. އެއުރެންގެ އަނގަތަކުން އެނުކުންނަ ބަހެއްގެ ބޮޑުކަމާއެވެ! އެއުރެން އެ ބުނަނީ، ދޮގެއްކަމުގައިނޫނީ ނުވެއެވެ.","",""],["","","","فلعلك باخع نفسك على آثارهم إن لم يؤمنوا بهذا الحديث أسفا","އެއުރެން މި ގުރްއާނަށް އީމާން ނުވިނަމަ، އެއުރެން ކަލޭގެފާނަށް މޫނުއަނބުރާލައި ދިޔަކަމުގެ މައްޗަށް ހިތާމައިން ކަލޭގެފާނުގެ ނަފްސު ހަލާކުކޮށްލައްވަނީތޯއެވެ؟ (އެބަހީ: އެހެން ނުހައްދަވާށެވެ!)","",""],["","","","إنا جعلنا ما على الأرض زينة لها لنبلوهم أيهم أحسن عملا","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، ބިންމަތީގައިވާހާ ތަކެއްޗެއް، އެ ބިމުގެ ޒީނަތެއްކަމުގައި ލެއްވީމެވެ. (އެއީ) އެއުރެންކުރެ އެންމެ ޢަމަލު ރަނގަޅީ ކާކުތޯ އިމްތިހާނުކުރެއްވުމަށެވެ.","",""],["","","","وإنا لجاعلون ما عليها صعيدا جرزا","އަދި ހަމަކަށަވަރުން، އެ ބިންމަތީގައިވާހާ ތަކެތި (ނެތިކުރައްވައި) ގަހެއް ރުކެއް ނެތް ހަނަފަސް ބިމެއްކަމުގައި ލައްވާހުށީމެވެ.","",""],["","","","أم حسبت أن أصحاب الكهف والرقيم كانوا من آياتنا عجبا","އަދި ކިއެއްތަ! ކަހުފު ބާގައިމީހުންނާއި، އެއުރެންގެ ނަންތަކާއި އެއުރެންގެ ޚަބަރުތައް ލިޔެވިފައިވާ ފިލާގެ ވާހަކައަކީ، ތިމަންރަސްކަލާނގެ އާޔަތްތަކުގެ ތެރެއިން އަޖާއިބަކަށްވީކަމުގައި، ކަލޭގެފާނު ހީފުޅުކުރެއްވީ ހެއްޔެވެ؟","",""],["","","","إذ أوى الفتية إلى الكهف فقالوا ربنا آتنا من لدنك رحمة وهيئ لنا من أمرنا رشدا","އެ ޒުވާނުން، އެ ހޮހަޅަޔަށް ވަންހިނދު، ހަނދުމަކުރާށެވެ! ފަހެ، އެ ޒުވާނުން ދެންނެވޫއެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! އިބަރަސްކަލާނގެ ހަޒުރަތުން އަޅަމެންނަށް ރަހުމަތެއް ދެއްވާނދޭވެ! އަދި އަޅަމެންގެ ކަންތަކަށް ސީދާގޮތެއް އަޅަމެންނަށް ފަހިކޮށްދެއްވާނދޭވެ!","",""],["","","","فضربنا على آذانهم في الكهف سنين عددا","ފަހެ، ހޮހަޅައިގައި އެތައް އަހަރެއްވާނދެން، ތިމަންރަސްކަލާނގެ އެއުރެން ގަދަނިއްޖެއްގައި ބައިތިއްބެވީމެވެ.","",""],["","","","ثم بعثناهم لنعلم أي الحزبين أحصى لما لبثوا أمدا","ދެން ތިމަންރަސްކަލާނގެ އެއުރެން (ނިދީން ހޭލައްވައި) އަލުން ފޮނުއްވީމެވެ. (އެއީ) އެއުރެން (ނިދާފައި) ތިބި މުއްދަތު އެންމެ ހަމަޔަށް ހިމަނަނީ، ދެބައިމީހުންކުރެ ކޮންބަޔެއްކަން ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގެންވާކަން ހާމަކުރެއްވުމަށެވެ.","",""],["","","","نحن نقص عليك نبأهم بالحق إنهم فتية آمنوا بربهم وزدناهم هدى","ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނަށް އެއުރެންގެ ޚަބަރު ތެދަށް ކިޔައިދެއްވަމެވެ. ހަމަކަށަވަރުން، އެއުރެންނީ އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް އީމާންވެ، އެއުރެންނަށް، ތިމަންރަސްކަލާނގެ ތެދުމަގު އިތުރުކުރައްވާފައިވާ ޒުވާން ފިރިހެނުން ތަކެކެވެ.","",""],["","","","وربطنا على قلوبهم إذ قاموا فقالوا ربنا رب السماوات والأرض لن ندعو من دونه إلها لقد قلنا إذا شططا","އަދި އެއުރެން ތެދުވެ، ތިމަންމެންގެ ވެރިރަސްކަލާނގެއީ، އުޑުތަކާއި ބިމުގެ ވެރިރަސްކަލާނގެއޭ، ތިމަންމެން އެކަލާނގެނޫން އިލާހަކަށް އަޅުކަމެއް ނުކުރާނޫއޭ ބުނިހިނދު، ތިމަންރަސްކަލާނގެ އެއުރެންގެ ހިތްތަކަށް ގަދަކަން ދެއްވީމެވެ. (އެނޫން ގޮތަކަށް ތިމަންމެން ބުނެފިނަމަ) ތިމަންމެން އޭރުން އެބުނީ، އަނިޔާވެރިކަމާއި، ކުފުރުގެ ނިހާޔަތަށް ގޮސްފައިވާ ބަހެއްކަން ކަށަވަރެވެ.","",""],["","","","هؤلاء قومنا اتخذوا من دونه آلهة لولا يأتون عليهم بسلطان بين فمن أظلم ممن افترى على الله كذبا","މިތިބީ އެކަލާނގެ ފިޔަވައި އަޅުކަންކުރުމަށް އިލާހުން ތަކެއް ހަދައިގެންތިބި، އަހަރެމެންގެ ގައުމުގެމީހުންނެވެ. (އެ ބުދުތަކަށް އަޅުކަންކުރުމަށް) ފާޅުވެގެންވާ ހުއްޖަތެއް، އެއުރެން ނުގެންނަނީ ކީއްވެގެންހެއްޔެވެ؟ ﷲއާމެދު ހަދައިގެން ދޮގެއްބުނި މީހަކަށްވުރެ، އަނިޔާވެރިކަންބޮޑު މީހަކީ ފަހެ ކާކުހެއްޔެވެ؟","",""],["","","","وإذ اعتزلتموهم وما يعبدون إلا الله فأووا إلى الكهف ينشر لكم ربكم من رحمته ويهيئ لكم من أمركم مرفقا","(އެ ޒުވާނުން އެއްބަޔަކު އަނެއްބަޔަކަށް ބުނޫއެވެ.) ތިޔަބައިމީހުން އެއުރެންނާ ވަކިވެ، އަދި ﷲ ފިޔަވައި އެއުރެން އަޅުކަންކުރާ ތަކެއްޗާ ވަކިވެގަންނަހިނދު، ތިޔަބައިމީހުން ހޮހަޅައިގެ ހިޔާވަހިކަން ލިބިގަންނާށެވެ! އޭރުން، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ، ތިޔަބައިމީހުންނަށް އެކަލާނގެ ރަހުމަތް ތަނަވަސްކޮށްދެއްވައި، ތިޔަބައިމީހުންގެ ކަންތައް، ތިޔަބައިމީހުންނަށް ފަހިކޮށްދެއްވައި، ބޭނުންތައް ޙާޞިލު ކޮށްދެއްވާނެތެވެ.","",""],["","","","وترى الشمس إذا طلعت تزاور عن كهفهم ذات اليمين وإذا غربت تقرضهم ذات الشمال وهم في فجوة منه ذلك من آيات الله من يهد الله فهو المهتد ومن يضلل فلن تجد له وليا مرشدا","އިރުއަރައިގެން އަންނަހިނދު، އެއުރެންގެ ހޮހަޅައިގެ ކަނާތްފަރާތަށް، އިރު ލަނބާލައިގެންދާތީ، ތިބާއަށް ފެންނާނެތެވެ. އަދި އިރުއޮއްސެންދާހިނދު، ވާތްފަރާތަށް އެއުރެން ދޫކޮށް ފަހަނަޅައިދެއެވެ. އޭރު އެއުރެންވަނީ، ހޮހަޅައިގެ ތަނަވަސް ތަނެއްގައެވެ. އެކަންތައްވަނީ، ﷲގެ އާޔަތް ތަކުގެތެރެއިންނެވެ. ﷲ ތެދުމަގު ދެއްކެވިމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކީ ތެދުމަގު ލިބިފައިވާ މީހެކެވެ. އަދި އެކަލާނގެ މަގުފުރައްދަވައިފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް ތެދުމަގު ދައްކާނޭ އެހީތެރިޔަކު ތިބާޔަކަށް ނުފެންނާނެތެވެ.","",""],["","","","وتحسبهم أيقاظا وهم رقود ونقلبهم ذات اليمين وذات الشمال وكلبهم باسط ذراعيه بالوصيد لو اطلعت عليهم لوليت منهم فرارا ولملئت منهم رعبا","އަދި އެއުރެން ނިދާފައި ތިބިއިރު، ތިބާޔަށް ހީވާނީ، ހޭލައިތިބި ބަޔެއްހެންނެވެ. އަދި ތިމަންރަސްކަލާނގެ އެއުރެން ކަނާތްފަރާތަށާއި، ވާތްފަރާތަށް ފުރޮޅުއްވަމެވެ. އަދި އެއުރެންގެ ކުއްތާ އޮތީ، އޭގެ ދެއަތް ދަމާލައިގެން (ހޮހަޅައިގެ) ދޮރުމަތީގައެވެ. އެއުރެންނަށް ތިބާ ބަލާލައިފިނަމަ، ހަމަކަށަވަރުން، ތިބާ އެއުރެންނާ ދުރަށްދުވެ ފިލާނެތެވެ. އަދި ހަމަކަށަވަރުން، ތިބާ އެއުރެންދެކެ ބިރުން ފިތްކަނޑައިގެން ހިނގައިދާނެތެވެ.","",""],["","","","وكذلك بعثناهم ليتساءلوا بينهم قال قائل منهم كم لبثتم قالوا لبثنا يوما أو بعض يوم قالوا ربكم أعلم بما لبثتم فابعثوا أحدكم بورقكم هذه إلى المدينة فلينظر أيها أزكى طعاما فليأتكم برزق منه وليتلطف ولا يشعرن بكم أحدا","އެފަދައިން ތިމަންރަސްކަލާނގެ އެއުރެން (ނިދިން ހޭލައްވައި) އަލުން ފޮނުއްވީމެވެ. (އެއީ) އެއުރެންގެ އެކަކު އަނެކަކާ ސުވާލުކުރުމަށެވެ. އެއުރެންކުރެ ބުނިމީހަކު ބުންޏެވެ. ތިޔަބައިމީހުން (މިތާނގައި) ތިބީ، ކިތައްދުވަހުހެއްޔެވެ؟ އެއުރެން ބުނޫއެވެ. ތިމަންމެންތިބީ، އެއްދުވަހު، ނުވަތަ ދުވަހެއްގެ ބައެއްގައެވެ. އެމީހުން ބުނޫއެވެ. ތިޔަބައިމީހުންތިބި މުއްދަތެއް ދެނެވޮޑިގަތުންބޮޑީ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއެވެ. ފަހެ، ތިޔަބައިމީހުންގެ މިފައިސާ ހިފައިގެން ތިޔަބައިމީހުންކުރެ އެކަކު، ރަށުތެރެއަށް ފޮނުވައިބަލާށެވެ! އެމީހަކު އެންމެރަނގަޅު، ހަލާލު ކާނާއެއް ބަލާހުށިކަމެވެ! އަދި އެއިން ކާއެތިކޮޅެއް ތިޔަބައިމީހުންނަށް ގެންނަހުށިކަމެވެ! އަދި އެމީހަކު ރައްކާތެރިކަމާއެކު، މަޑުމައިތިރިވެ އުޅޭހުށިކަމެވެ! އަދި އެއްވެސް މީހަކަށް ތިޔަބައިމީހުންގެ ޚަބަރު އެނގުނަދީގެން ނުވާނެއެވެ.","",""],["","","","إنهم إن يظهروا عليكم يرجموكم أو يعيدوكم في ملتهم ولن تفلحوا إذا أبدا","ހަމަކަށަވަރުން، އެއުރެންނަށް ތިޔަބައިމީހުންގެ ޚަބަރު އެނގިއްޖެނަމަ، ގަލުން ތަޅައި، ތިޔަބައިމީހުން މަރައިފާނެތެވެ. ނުވަތަ އެއުރެންގެ ދީނަށް ތިޔަބައިމީހުން ވައްދައިފާނެތެވެ. އޭރުން، ތިޔަބައިމީހުން ދުވަހަކުވެސް ނުދިނޭނެތެވެ.","",""],["","","","وكذلك أعثرنا عليهم ليعلموا أن وعد الله حق وأن الساعة لا ريب فيها إذ يتنازعون بينهم أمرهم فقالوا ابنوا عليهم بنيانا ربهم أعلم بهم قال الذين غلبوا على أمرهم لنتخذن عليهم مسجدا","އަދި ހަމައެފަދައިން، ތިމަންރަސްކަލާނގެ އެއުރެންނެރެ ދެއްކެވީމެވެ. އެއީ ﷲގެ ވައުދު ފުޅަކީ، ހައްގު ތެދުކަމާއި، ގިޔާމަތް ދުވަހާމެދު ޝައްކެއް ނެތްކަން އެއުރެން ދެނެގަތުމަށެވެ. އެހިނދު، އެ ޒުވާނުންގެ ކަންތަކާމެދު އެއްބަޔަކު އަނެއްބަޔަކާ ޒުވާބުކުރެތެވެ. ފަހެ، އެއްބަޔަކު ބުނޫއެވެ. އެ ޒުވާނުންގެ ވަށައިގެން ބިނާއެއް ހަދާށެވެ! އެ ޒުވާނުންގެ ކަންތައް ދެނެވޮޑިގަތުންބޮޑީ، އެއުރެންގެ ވެރިރަސްކަލާނގެއެވެ. އެއުރެންގެ ކަންތަކުގެ މައްޗަށް ގަދަވެގަތްމީހުން ބުނޫއެވެ. ހަމަކަށަވަރުން، ތިމަންމެން އެ ޒުވާނުން ތިބިތާނގައި، މިސްކިތެއް ބިނާކުރާނީއެވެ.","",""],["","","","سيقولون ثلاثة رابعهم كلبهم ويقولون خمسة سادسهم كلبهم رجما بالغيب ويقولون سبعة وثامنهم كلبهم قل ربي أعلم بعدتهم ما يعلمهم إلا قليل فلا تمار فيهم إلا مراء ظاهرا ولا تستفت فيهم منهم أحدا","އެއުރެން (ކުރެ ބަޔަކު) ބުނާނެތެވެ. އެއީ ތިންމީހުންނެވެ. އެއުރެންކުރެ ހަތަރުވަނައަކީ އެއުރެންގެ ކުއްތާއެވެ. އަދި އެއުރެން (ކުރެ ބަޔަކު) ބުނާނެތެވެ. އެއީ ފަސްމީހުންނެވެ. އެއުރެންގެ ހަވަނައަކީ އެއުރެންގެ ކުއްތާއެވެ. ހީއަކަށް ޣައިބުގެ ވާހަކަ ދައްކަނީއެވެ. އަދި އެއުރެން (ކުރެ ބަޔަކު) ބުނާނެތެވެ. އެއީ ހަތްމީހުންނެވެ. އެއުރެންގެ އަށްވަނައަކީ އެއުރެންގެ ކުއްތާއެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއުރެންގެ އަދަދު ދެނެވޮޑިގަތުންބޮޑީ، ތިމަންގެ ވެރިރަސްކަލާނގެއެވެ. މަދުބަޔަކަށްމެނުވީ އެއުރެންގެ އަދަދެއް ނޭނގެތެވެ. ފަހެ، ފާޅުވެގެންވާ ޖަދަލަކުން މެނުވީ، އެއުރެންނާ ދޭތެރޭގައި ކަލޭގެފާނު ޖަދަލު ނުކުރައްވާށެވެ! އަދި އެއުރެންނާ ދޭތެރޭގައި އެ ޖަދަލުކުރާ މީހުންކުރެ އެކަކާވެސް ކަލޭގެފާނު ސުވާލު ނުކުރައްވާށެވެ!","",""],["","","","ولا تقولن لشيء إني فاعل ذلك غدا","އަދި ކަލޭގެފާނު އެއްވެސްކަމަކާ ދޭތެރޭގައި، ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނު މާދަމާ އެކަމެއް ކުރައްވާނަމޭ ވިދާޅުނުވާހުށިކަމެވެ!","",""],["","","","إلا أن يشاء الله واذكر ربك إذا نسيت وقل عسى أن يهدين ربي لأقرب من هذا رشدا","ﷲ އިރާދަކުރެއްވިއްޔާއޭ ވިދާޅުވެފައި މެނުވީއެވެ. އަދި ކަލޭގެފާނު ހަނދުމަފުޅުނެތިއްޖެ ހިނދެއްގައި، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަނދުމަ ކުރައްވާށެވެ! އަދި ކަލޭގެފާނު ވިދާޅުވާށެވެ! އަޅުގެ ވެރިރަސްކަލާނގެ މިއަށްވުރެ ކައިރި ތެދުމަގަކަށް މިއަޅާއަށް މަގުދައްކަވައިފާށިއެވެ!","",""],["","","","ولبثوا في كهفهم ثلاث مائة سنين وازدادوا تسعا","އެއުރެންގެ ހޮހަޅައިގައި، އެއުރެން ތިންސަތޭކަ އަހަރާއި އަދި އިތުރަށް ނުވަ އަހަރު ތިބޫއެވެ.","",""],["","","","قل الله أعلم بما لبثوا له غيب السماوات والأرض أبصر به وأسمع ما لهم من دونه من ولي ولا يشرك في حكمه أحدا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއުރެން ތިބި މުއްދަތެއް ދެނެވޮޑިގަތުންބޮޑީ، ﷲއެވެ. އުޑުތަކާއި، ބިމުގެ ޣައިބު (ދެނެވޮޑިގަތުން) ވަނީ، އެކަލާނގެއަށެވެ. އެކަލާނގެ ބައްލަވާވޮޑިގަތުމާއި، އައްސަވާވޮޑިގަތުން ބޮޑުކަމާއެވެ! އެއުރެންނަށް އެކަލާނގެ ފިޔަވައި އެއްވެސް އެހީތެރިޔަކު ނުވެއެވެ. އަދި އެކަލާނގެ ހުކުމް ފުޅުގައި އެއްވެސްމީހަކު ބައިވެރިޔެއް ނުކުރައްވަތެވެ.","",""],["","","","واتل ما أوحي إليك من كتاب ربك لا مبدل لكلماته ولن تجد من دونه ملتحدا","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ފޮތުން، ކަލޭގެފާނަށް ވަހީކުރެއްވި ތަކެތި ކިޔަވައިވިދާޅުވާށެވެ! އެކަލާނގެ ކަލިމަ ފުޅުތަކަށް ބަދަލުގެނެވޭނޭ އެކަކުވެސް ނުވެއެވެ. އަދި އެކަލާނގެ ފިޔަވައި އެހީއަށްއެދި، އެނބުރި ވަޑައިގަންނަވާނެ ފަރާތެއް، ކަލޭގެފާނަކަށް ފެނިވަޑައެއް ނުގަންނަވާނެތެވެ.","",""],["","","","واصبر نفسك مع الذين يدعون ربهم بالغداة والعشي يريدون وجهه ولا تعد عيناك عنهم تريد زينة الحياة الدنيا ولا تطع من أغفلنا قلبه عن ذكرنا واتبع هواه وكان أمره فرطا","އަދި އެއުރެންގެ ވެރިރަސްކަލާނގެ ވަޖުހުފުޅު އެދިގެން، އެކަލާނގެއަށް ހެނދުނާއި، ހަވީރު ދުއާ ކޮށް އަޅުކަންކޮށްއުޅޭ މީހުންނާއެކު، ކަލޭގެފާނުގެ ނަފްސު ހިފަހައްޓަވައި، ކެތްކުރައްވާށެވެ! އަދި ދުނިޔޭގެ ދިރިއުޅުމުގެ ޒީނަތްތެރިކަން އެދިވަޑައިގެން، ކަލޭގެފާނުގެ ލޯފުޅު، އެއުރެން ފިޔަވައި ފަހަނަޅައި ދިޔަނުދެއްވާށެވެ! އަދި ތިމަންރަސްކަލާނގެ ހަނދުމަކުރުމުން، އެމީހެއްގެ ހިތް ޣާފިލުކުރައްވައި، އަދި އެމީހެއްގެ އަމިއްލަ އެދުމަށް ތަބާވެ، އަދި އެމީހެއްގެ ކަންތައް (ނުބައިކަމުގައި) ހައްދުފަހަނަޅައިފައިވާ މީހަކަށް، ކަލޭގެފާނު ކިޔަމަންވެ ވަޑައިނުގަންނަވާށެވެ!","",""],["","","","وقل الحق من ربكم فمن شاء فليؤمن ومن شاء فليكفر إنا أعتدنا للظالمين نارا أحاط بهم سرادقها وإن يستغيثوا يغاثوا بماء كالمهل يشوي الوجوه بئس الشراب وساءت مرتفقا","އަދި ކަލޭގެފާނު ވިދާޅުވާށެވެ! (އެއީ) ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައިސްފައިވާ ހައްގު ތެދެވެ. ފަހެ، ބޭނުންމީހަކު އީމާން ވާށެވެ! އަދި ބޭނުންމީހަކު ކާފިރު ވާށެވެ! ހަމަކަށަވަރުން، ކާފިރުވެ، އަނިޔާވެރިވެގަތް މީހުންނަށް، ތިމަންރަސްކަލާނގެ ނަރަކަ ތައްޔާރުކުރެއްވީމެވެ. އެ ނަރަކައިގެ (އަލިފާނުގެ) ފާރުތައް އެއުރެން ވަށާލައިގެންވެއެވެ. އެއުރެން ފެނަށްއެދި ގޮވާލައިފިނަމަ، އެއުރެންނަށް ދެއްވާނީ، ތެޔޮކުނޑިފަދަ (ހޫނުކަންގަދަ) ފެނެކެވެ. (އެއިން) މޫނުތައް ފިއްސައިލާނެތެވެ. (އެއުރެންނަށްލިބޭ) ބުއިމުގެ ނުބައިކަމާއެވެ! އަދި ތިބޭތަނެއްގެ ގޮތުން އެ ނަރަކައިގެ ނުބައިކަމާއެވެ!","",""],["","","","إن الذين آمنوا وعملوا الصالحات إنا لا نضيع أجر من أحسن عملا","ހަމަކަށަވަރުން، އީމާންވެ ސާލިހު ޢަމަލުތައްކުޅަމީހުން (ދަންނާށެވެ!) ހެޔޮކޮށް ކަންތައްކުޅަ މީހެއްގެ ދަރުމަ، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ގެއްލެނި ނުކުރައްވާހުށީމެވެ.","",""],["","","","أولئك لهم جنات عدن تجري من تحتهم الأنهار يحلون فيها من أساور من ذهب ويلبسون ثيابا خضرا من سندس وإستبرق متكئين فيها على الأرائك نعم الثواب وحسنت مرتفقا","އެއުރެންނަށް، ޢަދަން އޭ ކިއުނު ސުވަރުގެތައް ހުށްޓެވެ. އެއުރެންގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުރެއެވެ. އެތާނގައި ރަނުގެ އުޅާތަކުން އެއުރެންގައި ގަހަނާ އަޅުއްވާނެތެވެ. އަދި ފެހިކުލައިގެ ސުންދުސާއި އިސްތަބްރަގު (އެބަހީ: ފަލަފަށުއި) ފޭރާން ލާނެތެވެ. އެތާނގައި އެއުރެން ދާންތަކުގެ މަތީގައި ލެނގިލައިގެންތިބޭ ޙާލު ގައެވެ. (އެއުރެންނަށްހުރި) ސަވާބުގެ މޮޅުކަމާއެވެ! އަދި (އެއުރެން) ތިބެނިވިތަނެއްގެ ގޮތުން އެތާނގެ ރަނގަޅުކަމާއެވެ!","",""],["","","","واضرب لهم مثلا رجلين جعلنا لأحدهما جنتين من أعناب وحففناهما بنخل وجعلنا بينهما زرعا","ކަލޭގެފާނު އެއުރެންނަށް ދެފިރިހެނެއްގެ މިސާލު ޖައްސަވައިދެއްވާށެވެ! އެ ދެމީހުންކުރެ އެކަކަށް، މޭބިސްކަދުރުގެ ދެ ބަގީޗާ ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ. އަދި އެ ދެ ބަގީޗާގެ ވަށައިގެން ކަދުރުރުއްތައް ލެއްވީމެވެ. އަދި އެދެމެދުގައި ދަނޑުގޮވާންވެސް ލެއްވީމެވެ.","",""],["","","","كلتا الجنتين آتت أكلها ولم تظلم منه شيئا وفجرنا خلالهما نهرا","އެ ދެ ބަގީޗާގައިމެ، މޭވާއައިސް އެއިން އެއްވެސް އެއްޗެއް އުންޏެއް ނުވެއެވެ. އަދި އެ ދެ ބަގީޗާގެ ދެމެދުން ކޯރެއް ހިންގެވީމެވެ.","",""],["","","","وكان له ثمر فقال لصاحبه وهو يحاوره أنا أكثر منك مالا وأعز نفرا","އަދި އޭނާއަށް (އެހެނިހެން) މުދާތައްވެސްވެއެވެ. ފަހެ، އޭނާ، އޭނާގެ އެކުވެރިޔާއާ ވާހަކަދައްކަމުން (ބޮޑާވެފައި) ބުންޏެވެ. ކަލެޔަށްވުރެ އަހުރެންގެ މުދާ ގިނައެވެ. އަދި (އަހުރެންގެ ދަށުގައިވާ) މީހުން ގިނަކަމުގެގޮތުން، ގަދަފަދަވެފައި ޢިއްޒަތް ބޮޑެވެ.","",""],["","","","ودخل جنته وهو ظالم لنفسه قال ما أظن أن تبيد هذه أبدا","އަދި އޭނާގެ އަމިއްލަ ނަފްސަށް އަނިޔާވެރިވެގެންވާ ޙާލު، އޭނާގެ ބަގީޗާއަށް ވަދެބުންޏެވެ. ދުވަހަކުވެސް މިތަކެތި ހަލާކުވެ ފަނާވެދާނެކަމަށް އަހުރެން ހީއެއް ނުކުރަމެވެ.","",""],["","","","وما أظن الساعة قائمة ولئن رددت إلى ربي لأجدن خيرا منها منقلبا","އަދި ގިޔާމަތް ވާނޭ ކަމަކަށްވެސް އަހުރެން ހީއެއް ނުކުރަމެވެ. އަދި އަހުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް އަހުރެން ރައްދުކުރެއްވިޔަސް މިއަށްވުރެ ރަނގަޅުގޮތް، އަހުރެންނަށް ފެންނާނެކަން ކަށަވަރެވެ.","",""],["","","","قال له صاحبه وهو يحاوره أكفرت بالذي خلقك من تراب ثم من نطفة ثم سواك رجلا","(ޖަވާބުގައި) އޭނާގެ އެކުވެރިޔާ އޭނާއާ ވާހަކަ ދައްކަމުން އޭނާއަށް ބުންޏެވެ. ވެލިން ކަލޭހައްދަވައި (އެބަހީ: އާދަމުގެފާނު ހައްދަވައި) ދެން މަނިފޮދަކުން ކަލޭ ހައްދަވައި، ދެން ފުރިހަމަ ފިރިހެނަކަށް ކަލޭ ހެއްދެވި ރަސްކަލާނގެއަށް ކަލޭ ކާފިރު ވީ ހެއްޔެވެ؟","",""],["","","","لكنا هو الله ربي ولا أشرك بربي أحدا","އެހެނެއްކަމަކު، އެއީ އަހުރެންގެވެރި ﷲއެވެ. އަދި އަހުރެންގެ ވެރިރަސްކަލާނގެއަށް އެކަކުވެސް އަހުރެން ޝަރީކެއް ނުކުރަމެވެ.","",""],["","","","ولولا إذ دخلت جنتك قلت ما شاء الله لا قوة إلا بالله إن ترن أنا أقل منك مالا وولدا","އަދި ކަލޭގެ ބަގީޗާއަށް، ކަލޭ ވަންހިނދު، ﷲ އިރާދަކުރެއްވިކަމެއްވާނެއޭ ބުނިނަމަ، ކޮންފަދަހެއްޔެވެ! އެއްވެސް ބާރެއް ﷲގެ ހަޒުރަތުން މެނުވީ ނުވެއެވެ. ކަލެޔަށްވުރެ އަހުރެންގެ މުދަލާއި ދަރިން މަދުކަމުގައި ކަލެޔަށް ފެނުނަސް، ފަހެ، ކަލޭގެ ބަގީޗާއަށްވުރެ މާހެޔޮވެގެންވާ ނިއުމަތް އަހުރެންގެ ވެރިރަސްކަލާނގެ އަހުރެންނަށް ދެއްވައިފާށިއެވެ! އަދި އެ ބަގީޗާގެ މައްޗަށް އުޑުން އާފާތެއް ފޮނުއްވައި، ގަހެއް ރުކެއްނެތް އޮމާން ބިމަކަށް އެތަންވެދާނެތެވެ.","",""],["","","","فعسى ربي أن يؤتين خيرا من جنتك ويرسل عليها حسبانا من السماء فتصبح صعيدا زلقا","އަދި ކަލޭގެ ބަގީޗާއަށް، ކަލޭ ވަންހިނދު، ﷲ އިރާދަކުރެއްވިކަމެއްވާނެއޭ ބުނިނަމަ، ކޮންފަދަހެއްޔެވެ! އެއްވެސް ބާރެއް ﷲގެ ހަޒުރަތުން މެނުވީ ނުވެއެވެ. ކަލެޔަށްވުރެ އަހުރެންގެ މުދަލާއި ދަރިން މަދުކަމުގައި ކަލެޔަށް ފެނުނަސް، ފަހެ، ކަލޭގެ ބަގީޗާއަށްވުރެ މާހެޔޮވެގެންވާ ނިއުމަތް އަހުރެންގެ ވެރިރަސްކަލާނގެ އަހުރެންނަށް ދެއްވައިފާށިއެވެ! އަދި އެ ބަގީޗާގެ މައްޗަށް އުޑުން އާފާތެއް ފޮނުއްވައި، ގަހެއް ރުކެއްނެތް އޮމާން ބިމަކަށް އެތަންވެދާނެތެވެ.","",""],["","","","أو يصبح ماؤها غورا فلن تستطيع له طلبا","ނުވަތަ އެތާނގެ ފެން، ބިންގަނޑުގެ ތެރެޔަށް އަޑިޔަށް ހިނގައިދާނެތެވެ. ދެން އެ ފެން އަތުލުމަކަށް ކަލެޔަކަށް ކުޅަދާނަވެގެނެއް ނުވާނެތެވެ.","",""],["","","","وأحيط بثمره فأصبح يقلب كفيه على ما أنفق فيها وهي خاوية على عروشها ويقول يا ليتني لم أشرك بربي أحدا","އަދި އޭނާގެ މުދާތައް (ބަގީޗާއާއެކު) ހަލާކުވެ ހިނގައްޖެއެވެ. އަދި އެ ބަގީޗާގެ ގަސްތައް، އަށިގަނޑުތަކާއެކު ވެއްޓިފައިވާ ޙާލު، އެ ބަގީޗާ ހެއްދުމަށް އޭނާކުޅަ ޚަރަދުތަކުގެ މައްޗަށް، ހިތާމައިން ދެއަތް ފުރޮޅަފުރޮޅައިހުރެ ބުނެތެވެ. އޭ ސަހަރޯއެވެ! އަހުރެންގެ ވެރިރަސްކަލާނގެއާ އެކަކުވެސް އަހުރެން ޝަރީކު ނުކުރިނަމަ، ކިހާ ރަނގަޅުވީސްހެއްޔެވެ؟","",""],["","","","ولم تكن له فئة ينصرونه من دون الله وما كان منتصرا","އަދި ﷲ ފިޔަވައި، އޭނާއަށް ނަސްރު ދޭނޭ ބަޔަކު އޭނާއަކަށް ނުވިއެވެ. އަދި އޭނާއަކީ، ނަސްރު ލިބޭނޭ މީހަކު ކަމުގައިވެސް ނުވިއެވެ.","",""],["","","","هنالك الولاية لله الحق هو خير ثوابا وخير عقبا","އެތާނގައި (އެބަހީ: ގިޔާމަތް ދުވަހުން) އެހީތެރިކަން ދެއްވުން މަލަކަ ވެގެންވަނީ، ހައްގުވަންތަ ﷲއަށެވެ. އެކަލާނގެއީ، ސަވާބު ދެއްވުމުގައި އެންމެހެޔޮ ރަސްކަލާނގެއެވެ. އަދި އެންމެފަހުގެ ނިމުން ދެއްކެވުމުގައި، އެންމެހެޔޮ ރަސްކަލާނގެއެވެ.","",""],["","","","واضرب لهم مثل الحياة الدنيا كماء أنزلناه من السماء فاختلط به نبات الأرض فأصبح هشيما تذروه الرياح وكان الله على كل شيء مقتدرا","ކަލޭގެފާނު އެއުރެންނަށް ދުނިޔޭގެ ދިރިއުޅުމުގެ މިސާލު ޖައްސަވައިދެއްވާށެވެ! ތިމަންރަސްކަލާނގެ އުޑުންވެއްސެވި ފެނެއްގެ މިސާލެވެ. ދެން ބިމުގެ ގަސްތައް އެ ފެނާއެކުވެ (ތާޒާކަންލިބި ހެދިގަތުމަށްފަހު) ވަޔާބުރައިގެންދާ ހިކި ކުނޑިތަކަކަށްވެދެއެވެ. ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ކަލަކުކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","المال والبنون زينة الحياة الدنيا والباقيات الصالحات خير عند ربك ثوابا وخير أملا","މުދަލާއި ދަރިންނަކީ ދުނިޔޭގެ ދިރިއުޅުމުގެ ޒީނަތްތެރިކަމެވެ. އަދި ދެމިހުންނަނިވި ސާލިހު ޢަމަލުތައް، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ސަވާބުގެގޮތުން މާހެޔޮކަން ބޮޑެވެ. އަދި އެދޭ އެދުމެއްގެ ގޮތުން މާހެޔޮކަން ބޮޑުމެއެވެ.","",""],["","","","ويوم نسير الجبال وترى الأرض بارزة وحشرناهم فلم نغادر منهم أحدا","އަދި ތިމަންރަސްކަލާނގެ ފަރުބަދަތައް ލުހެލައްވައި، ފުނޑުފުނޑުކޮށްލައްވާ ދުވަސް ހަނދުމަކުރާށެވެ! (އެދުވަހުން) ބިންގަނޑު ހަމަހަމަވެ ފާޅުވެގެންވާތީ ތިބާދެކޭނޫއެވެ. އަދި އެއުރެން މަހުޝަރަށް ފޮނުއްވާހުށީމެވެ. ފަހެ، އޭގެތެރެއިން ހަމައެކަކުވެސް ދޫނުކުރައްވާހުށީމެވެ.","",""],["","","","وعرضوا على ربك صفا لقد جئتمونا كما خلقناكم أول مرة بل زعمتم ألن نجعل لكم موعدا","އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ސަފުސަފަށް އެއުރެން ހުށަހެޅޭނެތެވެ. (އަދި ﷲ ވަހީކުރައްވާނެތެވެ.) ތިމަންރަސްކަލާނގެ އެންމެފުރަތަމަފަހަރު ތިޔަބައިމީހުން ހެއްދެވިފަދައިން، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ތިޔަބައިމީހުން އަތުވެއްޖައީމުއެވެ. އަދި ކީއްހެއްޔެވެ! ތިޔަބައިމީހުން ހީކުޅައީ (މަހުޝަރަށް ފޮނުއްވުމަށް) ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް ވަގުތެއް ކަނޑަނާޅުއްވާނޭކަމަށެވެ.","",""],["","","","ووضع الكتاب فترى المجرمين مشفقين مما فيه ويقولون يا ويلتنا مال هذا الكتاب لا يغادر صغيرة ولا كبيرة إلا أحصاها ووجدوا ما عملوا حاضرا ولا يظلم ربك أحدا","އަދި (ކޮންމެ މީހަކުމެ ކޮށްފައިވާ ޢަމަލުތަކުގެ) ފަތް (އެމީހަކަށް) ދެއްވާނެތެވެ. ފަހެ، އެ ފަތުގައިވާ ތަކެއްޗާމެދު، ކުށްވެރިން ބިރުގެންފައިވާތީ ތިބާ ދެކޭނޫއެވެ. އަދި އެއުރެން ބުނާނެތެވެ. އޭ ތިމަންމެންނަށްހުރި ހިތާމައެއްގެ ބޮޑުކަމާއެވެ! މިފަތަށް މިވެފައިވަނީ ކީއްހެއްޔެވެ؟ ކިތަންމެ ކުޑަކަމެއްވެސް، އަދި ބޮޑުކަމެއްވެސް، އެ ފަތުގައި ނުހިމަނައި ދޫކޮށްލައިފައެއް ނުވެއެވެ. އަދި އެއުރެންކުޅަ އެންމެހައި ޢަމަލުތައް އެ ފަތުގައިވާތީ، އެއުރެން ދެކޭނެތެވެ. ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެއްވެސްމީހަކަށް އަނިޔާވެރިވެވޮޑިއެއް ނުގަންނަވަތެވެ.","",""],["","","","وإذ قلنا للملائكة اسجدوا لآدم فسجدوا إلا إبليس كان من الجن ففسق عن أمر ربه أفتتخذونه وذريته أولياء من دوني وهم لكم عدو بئس للظالمين بدلا","ތިމަންރަސްކަލާނގެ މަލާއިކަތުންނަށް ވަހީކުރެއްވިހިނދު، ހަނދުމަކުރާށެވެ! ތިޔަބައިމީހުން އާދަމުގެފާނަށް ސަޖިދަކުރާށެވެ! ދެން އިބްލީސް މެނުވީ، އެ އެންމެ ބޭކަލުން ސަޖިދަކުރެއްވޫއެވެ. އެ އިބްލީސް ވީ ޖިންނީންގެ ތެރެއިންނެވެ. ދެން އޭނާގެ ވެރިރަސްކަލާނގެ އަމުރުފުޅަށް އޭނާ ނުކިޔަމަންތެރިވިއެވެ. ފަހެ، އެ އިބްލީސާއި، އޭނާގެ ދަރިފަސްކޮޅު، ތިމަންރަސްކަލާނގެ ފިޔަވައި އެހީތެރިން ކަމުގައި ތިޔަބައިމީހުން ހަދަނީ ހެއްޔެވެ؟ އެއުރެންނަކީ، ތިޔަބައިމީހުންނަށްހުރި އަދުއްވުންނެވެ. އަނިޔާވެރިންނަށްހުރި ބަދަލެއްގެ ނުބައިކަމާއެވެ!","",""],["","","","ما أشهدتهم خلق السماوات والأرض ولا خلق أنفسهم وما كنت متخذ المضلين عضدا","އުޑުތަކާއި، ބިން ހެއްދެވުމުގައި، ތިމަންރަސްކަލާނގެ އެއުރެން ހެތްކެއް ނުކުރައްވަމެވެ. އަދި އެއުރެންގެ އަމިއްލަ ނަފްސުތައް ހެއްދެވުމުގައިވެސްމެއެވެ. އަދި މަގުފުރައްދާ ޝައިތާނުންނީ، އެހީތެރިންކަމުގައި ތިމަންރަސްކަލާނގެ ނުހިއްޕަވަމެވެ.","",""],["","","","ويوم يقول نادوا شركائي الذين زعمتم فدعوهم فلم يستجيبوا لهم وجعلنا بينهم موبقا","އަދި ތިމަންރަސްކަލާނގެ ބައިވެރިންކަމުގައި ތިޔަބައިމީހުން ހީކޮށްގެން އުޅުނު ތަކެއްޗަށް، ތިޔަބައިމީހުން ގޮވައިބަލާށޭ އެކަލާނގެ ވަހީކުރައްވާ ދުވަސް ހަނދުމަކުރާށެވެ! ފަހެ، އެއުރެން އެތަކެއްޗަށް ގޮވާނެތެވެ. ނަމަވެސް އެތަކެތި އެއުރެންނަކަށް ޖަވާބެއް ނުދޭނެތެވެ. އަދި އެއުރެންގެ މެދުގައި ހުރަހެއް (އެބަހީ: ނަރަކައިގެ ވާދީއެއް) ތިމަންރަސްކަލާނގެ ލައްވާހުށީމެވެ.","",""],["","","","ورأى المجرمون النار فظنوا أنهم مواقعوها ولم يجدوا عنها مصرفا","ކުށްވެރިންނަށް ނަރަކަ ފެނި، އެ ނަރަކައަށް އެއުރެން ވެއްޓޭނޭކަމުގައި އެއުރެންނަށް ޔަގީން ވާނެތެވެ. އަދި އެ ނަރަކައާ ދުރަށް ފިލަންދާނޭ ތަނެއް އެއުރެންނަކަށް ނުފެންނާނެތެވެ.","",""],["","","","ولقد صرفنا في هذا القرآن للناس من كل مثل وكان الإنسان أكثر شيء جدلا","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ މި ގުރްއާންގައި ހުރިހާ ބާވަތަކުންވެސް މީސްތަކުންނަށް މިސާލު ބަޔާންކުރެއްވީމެވެ. އަދި ޖަދަލުކުރުންގިނަ މީހަކުކަމުގައި އިންސާނާ ވިއެވެ.","",""],["","","","وما منع الناس أن يؤمنوا إذ جاءهم الهدى ويستغفروا ربهم إلا أن تأتيهم سنة الأولين أو يأتيهم العذاب قبلا","އިސްވެދިޔަމީހުންނަށް ވެގެންދިޔަގޮތް އެއުރެންނަށްވެސްވުން، ނުވަތަ އެއުރެންނަށް ފެންނަގޮތުގައި އަޒާބު އައުން (އެބަހީ: އެކަމަށްއެދި އިންތިޒާރުކުރުން) މެނުވީ، މީސްތަކުންނަށް ތެދުމަގު އައިހިނދު، އެއުރެން އީމާން ވުމާއި، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ފާފަފުއްސެވުންއެދި ދެންނެވުން، އެއުރެންނަށް މަނާއެއް ނުކުރެތެވެ.","",""],["","","","وما نرسل المرسلين إلا مبشرين ومنذرين ويجادل الذين كفروا بالباطل ليدحضوا به الحق واتخذوا آياتي وما أنذروا هزوا","އަދި އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލުންކަމުގައްޔާއި، އިންޒާރުކުރައްވާ ބޭކަލުންކަމުގައި މެނުވީ، ތިމަންރަސްކަލާނގެ ރަސޫލުން ނުފޮނުއްވަމެވެ. އަދި ކާފިރު ވީ މީހުން ބާތިލު ގޮތުން ޖަދަލުކުރެތެވެ. (އެއީ) އެގޮތުން އެއުރެން، ހައްގަކީ، ބާތިލެއްޗެއް ކަމުގައި ހެދުމަށެވެ. އަދި ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާއި، އެއުރެންނަށް އިންޒާރުކުރައްވާފައިވާ ކަންތައް ފުރައްސާރައެއްކަމުގައި އެއުރެން ހެދޫއެވެ.","",""],["","","","ومن أظلم ممن ذكر بآيات ربه فأعرض عنها ونسي ما قدمت يداه إنا جعلنا على قلوبهم أكنة أن يفقهوه وفي آذانهم وقرا وإن تدعهم إلى الهدى فلن يهتدوا إذا أبدا","އެމީހެއްގެ ވެރިރަސްކަލާނގެ އާޔަތް ތަކުން އެމީހަކަށް ހަނދާންކޮށްދެއްވުމުން، އެ އާޔަތްތަކަށް ފުރަގަސްދީ، އެނބުރިގަނެ، އަދި އޭނާ އިސްކުޅަ ޢަމަލުތައް ހަނދާންނެތުނު މީހާއަށްވުރެ އަނިޔާވެރިކަންބޮޑީ ފަހެ، ކާކުހެއްޔެވެ؟ ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް އެ ގުރްއާން ވިސްނުމަށް ހުރަސްއަޅާ ހުރަސްތަކެއް، އެއުރެންގެ ހިތްތަކުގައި ލެއްވީމެވެ. އަދި އެއުރެންގެ ކަންފަތްތަކުގައި ބީރުކަމެއް ލެއްވީމެވެ. އަދި ކަލޭގެފާނު އެއުރެންނަށް ތެދުމަގަށް ގޮވައިލައްވައިފިނަމަ، ފަހެ، އޭރުން އެއްގޮތަކަށްވެސް އެއުރެން ތެދުމަގު ލިބިއެއް ނުގަންނާނެތެވެ.","",""],["","","","وربك الغفور ذو الرحمة لو يؤاخذهم بما كسبوا لعجل لهم العذاب بل لهم موعد لن يجدوا من دونه موئلا","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަހުމަތްގެ ވެރިރަސްކަލާނގެއެވެ. އެއުރެން ހޯދި (ނުބައި) ކަންތަކަށް އެކަލާނގެ އެއުރެންނަށް (ވަގުތުން) ޢިގާބު ދެއްވާނަމަ، އެއުރެންނަށް އަޒާބު އަވަސްކުރެއްވީސްކަން ކަށަވަރެވެ. އަދި ކީއްހެއްޔެވެ! އެއުރެންނަށް މައުޢިދެއް ވެއެވެ. އެއިން ރެކިގެންގޮސް ވަންނާނެ ތަނެއް އެއުރެންނަކަށް ނުފެންނާނެތެވެ.","",""],["","","","وتلك القرى أهلكناهم لما ظلموا وجعلنا لمهلكهم موعدا","އަދި އެއީ އެއުރެން އަނިޔާވެރިވީހިނދު، ތިމަންރަސްކަލާނގެ ހަލާކު ކުރެއްވި ރަށްތަކުގެ މީހުންނެވެ. އަދި އެއުރެން ހަލާކުވެދިއުމަށް ކަނޑައެޅިގެންވާ ވަގުތެއް ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ.","",""],["","","","وإذ قال موسى لفتاه لا أبرح حتى أبلغ مجمع البحرين أو أمضي حقبا","މޫސާގެފާނު އެކަލޭގެފާނުގެ ޚާދިމު ކުއްޖާއަށް ވިދާޅުވިހިނދު ހަނދުމަކުރާށެވެ! ދެކަނޑު ގުޅުނު ހިސާބަށް ތިމަންކަލޭގެފާނު ފޯރައްޖައުމަށް ދާނދެން، ނުވަތަ ޒަމާންތަކެއް ވޭތިކުރައްވައިފުމަށްދާނދެން (ހިންގެވުން) ދުލެއް ނުކުރައްވާހުށީމެވެ.","",""],["","","","فلما بلغا مجمع بينهما نسيا حوتهما فاتخذ سبيله في البحر سربا","ފަހެ، އެ ދެކަނޑު ދެމެދު ގުޅުނު ހިސާބަށް އެ ދެކަލުންނަށް ވާޞިލު ވެވުނު ހިނދު، އެ ދެކަލުންގެ (އެކުގައި ގެންދެވި ލޮނުއެޅި) މަހުގެ މަތިން އެ ދެކަލުން ހަނދުމަނެތިއްޖެއެވެ. ފަހެ (އޭރު) އެ މަސް ހަނިހަނިމަގަކުން ލައިގެން ކަނޑުގެތެރެއަށް ހިނގައްޖެއެވެ.","",""],["","","","فلما جاوزا قال لفتاه آتنا غداءنا لقد لقينا من سفرنا هذا نصبا","ފަހެ، އެ ދެކަލުން (އެތަން) ފަހަނަޅައި ވަޑައިގެންނެވިހިނދު، އެކަލޭގެފާނުގެ ޚާދިމު ކުއްޖާއަށް އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިމަންމެންގެ ދުވާލުގެ ކެއުން ތިމަންމެންނަށް ގެނެސްދޭށެވެ! ހަމަކަށަވަރުން، ތިމަންމެންގެ މި ދަތުރުން ތިމަންމެންނަށް ވަރަށްބޮޑު ވަރުބަލިކަމެއް ލިބިއްޖެއެވެ.","",""],["","","","قال أرأيت إذ أوينا إلى الصخرة فإني نسيت الحوت وما أنسانيه إلا الشيطان أن أذكره واتخذ سبيله في البحر عجبا","އެ ޚާދިމު ދެންނެވިއެވެ. ކަލޭގެފާނަށް އެނގިވަޑައިގެންވޭތޯއެވެ؟ (ދެކަނޑު ގުޅުނުތާ އޮތް) ބޮޑު ހިލައިގެމަތީގައި ތިމަންމެން މަޑުކޮށްލިހިނދު، ހަމަކަށަވަރުން، ތިމަން އެ މަހުގެމަތިން ހަނދާންނެތުނީއެވެ. އަދި އެ މަހުގެމަތިން ތިމަން ހަނދާންކުރުން ހަނދާންނެތިކޮށްލީ، ޝައިތާނާ ފިޔަވައި އެހެން އެއްޗެއްނޫނެވެ. އަދި އެ މަސް އަޖާއިބެއްފަދަ ގޮތަކަށް ކަނޑުގެ ތެރެއިން އޭގެމަގު ހޯދައިގެން ހިނގައްޖެއެވެ.","",""],["","","","قال ذلك ما كنا نبغ فارتدا على آثارهما قصصا","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިމަންމެން ބޭނުންވެގެން މިއުޅެނީ އެތަނެވެ. ދެން އެ ދެކަލުންގެ ފިޔަވަޅު ބައްލަވަމުން އެ ދެކަލުން އެނބުރި ފަހަތަށް ވަޑައިގެންފިއެވެ.","",""],["","","","فوجدا عبدا من عبادنا آتيناه رحمة من عندنا وعلمناه من لدنا علما","ދެން (އެތަނުން) އެ ދެކަލުންނަށް ތިމަންރަސްކަލާނގެ އަޅުންގެ ތެރެއިން (ހާއްސަ) އަޅަކު ފެނިވަޑައިގަތެވެ. އެބޭކަލަކަށް ތިމަންރަސްކަލާނގެ ހަޒުރަތުން ރަހުމަތެއް ދެއްވީމެވެ. އަދި އެބޭކަލަކަށް ތިމަންރަސްކަލާނގެ ހަޒުރަތުން ހާއްސަ އިލްމެއް އުނގަންނައިދެއްވީމެވެ.","",""],["","","","قال له موسى هل أتبعك على أن تعلمن مما علمت رشدا","އެބޭކަލަކަށް މޫސާގެފާނު ވިދާޅުވިއެވެ. ކަލޭގެފާނަށް ދެއްވާފައިވާ އިލްމުން ތިމަންކަލޭގެފާނަށް އުނގަންނަވައިދެއްވާންކަމަށް، ކަލޭގެފާނަށް ތިމަންކަލޭގެފާނު ތަބާ ވަންތޯއެވެ؟","",""],["","","","قال إنك لن تستطيع معي صبرا","އެބޭކަލަކު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނަކަށް ތިމަންކަލޭގެފާނާ އެކުގައި ކެތްކުރެއްވުމަކަށް ކުޅަދާނަވެގެނެއް ނުވާނެތެވެ.","",""],["","","","وكيف تصبر على ما لم تحط به خبرا","ކަލޭގެފާނަށް އެކަމެއްގެ ހަގީގަތް އެނގިވަޑައިނުގަންނަވާ ކަމެއްގެ މައްޗަށް ކަލޭގެފާނަށް ކެތްކުރެއްވޭނީ ފަހެ، ކޮންފަދައަކުންތޯއެވެ؟","",""],["","","","قال ستجدني إن شاء الله صابرا ولا أعصي لك أمرا","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ﷲ އިރާދަކުރެއްވިއްޔާ، ތިމަންކަލޭގެފާނީ ކެތްތެރިޔަކުކަމުގައި ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނޫއެވެ. އަދި އެއްވެސް އަމުރަކަށް ކަލޭގެފާނަށް ތިމަންކަލޭގެފާނު ނުކިޔަމަންތެރިވެވަޑައެއް ނުގަންނަވާނަމެވެ.","",""],["","","","قال فإن اتبعتني فلا تسألني عن شيء حتى أحدث لك منه ذكرا","އެބޭކަލަކު ވިދާޅުވިއެވެ. ފަހެ، ކަލޭގެފާނު ތިމަންކަލޭގެފާނާއެކު ވަޑައިގަންނަވަނީނަމަ، އެކަމެއްގެ ވާހަކައިން ތިމަންކަލޭގެފާނު ކަލޭގެފާނަށް ބަޔާންކޮށްދެއްވައިފުމަށް ދާންދެން އެއްވެސް ކަމަކާ ދޭތެރޭ ތިމަންކަލޭގެފާނާ ސުވާލު ނުކުރައްވާށެވެ!","",""],["","","","فانطلقا حتى إذا ركبا في السفينة خرقها قال أخرقتها لتغرق أهلها لقد جئت شيئا إمرا","ދެން އެ ދެބޭކަލުން ކުރިޔަށް ހިންގަވައި ވަޑައިގެން، ނަވަށް އަރައިވަޑައިގެންނެވިހިނދު، އެބޭކަލަކު އެ ނައު ފޫދުއްވައިލައްވައިފިއެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އެ ނައު ތިޔަ ފޫދުއްވައިލެއްވީ އޭގެ އަހުލުވެރިން ޣަރަގު ކޮށްލެއްވުމަށްތޯއެވެ؟ ހަމަކަށަވަރުން، ކަލޭގެފާނު ތިޔަކުރެއްވީ ބޮޑުވެގެންވާ ނުބައިކަމެކެވެ.","",""],["","","","قال ألم أقل إنك لن تستطيع معي صبرا","އެބޭކަލަކު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނާއެކުގައި ކަލޭގެފާނަށް ކެތްކުރެއްވުމަކަށް ކުޅަދާނައެއް ނުވާނެއޭ ތިމަންކަލޭގެފާނު ނުދަންނަވަންތޯއެވެ؟","",""],["","","","قال لا تؤاخذني بما نسيت ولا ترهقني من أمري عسرا","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިމަންކަލޭގެފާނު ހަނދުމަފުޅުނެތުން ކަލޭގެފާނު، ކަމަކަށް ނުހައްދަވާށެވެ! އަދި ތިމަންކަލޭގެފާނުގެ ކަންތަކަށް ދަތިކަމެއް، އުނދަގުލެއް ނުޖައްސަވާށެވެ!","",""],["","","","فانطلقا حتى إذا لقيا غلاما فقتله قال أقتلت نفسا زكية بغير نفس لقد جئت شيئا نكرا","ދެން އެދެބޭކަލުން ކުރިޔަށް ހިންގަވައި ވަޑައިގަންނަވަނިކޮށް، ކުޑަފިރިހެންކުއްޖަކާ ބައްދަލުވެވަޑައިގެންނެވި ހިނދު، އެބޭކަލަކު އެކުއްޖާ ގަތުލުކުރައްވައިފިއެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އެކަކުވެސް މަރާފައިނުވާ، ކުށެއްނެތް، ތާހިރު ނަފްސެއް، ކަލޭގެފާނު ތިޔަ ގަތުލުކުރެއްވީތޯއެވެ؟ ހަމަކަށަވަރުން، ކަލޭގެފާނު ތިޔަކުރެއްވީ ވަރަށްބޮޑު ނުބައިކަމެކެވެ.","",""],["","","","قال ألم أقل لك إنك لن تستطيع معي صبرا","އެބޭކަލަކު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނާ އެކުގައި ކަލޭގެފާނަށް ކެތްކުރެއްވުމަކަށް ކުޅަދާނައެއް ނުވާނެއޭ، ތިމަންކަލޭގެފާނު ކަލޭގެފާނަކަށް ނުދަންނަވަންތޯއެވެ؟","",""],["","","","قال إن سألتك عن شيء بعدها فلا تصاحبني قد بلغت من لدني عذرا","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. މީގެފަހުން އެއްވެސް ކަމަކާމެދު، ކަލޭގެފާނާ ތިމަންކަލޭގެފާނު ސުވާލުކުރައްވައިފިނަމަ، ކަލޭގެފާނާއެކު ތިމަންކަލޭގެފާނު ނުގެންދަވާށެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުގެ ކިބައިން ކަލޭގެފާނަށް ޢުޛުރެއް ލިބިވަޑައިގެންފިއެވެ.","",""],["","","","فانطلقا حتى إذا أتيا أهل قرية استطعما أهلها فأبوا أن يضيفوهما فوجدا فيها جدارا يريد أن ينقض فأقامه قال لو شئت لاتخذت عليه أجرا","ދެން އެ ދެބޭކަލުން ކުރިޔަށް ހިންގަވައިވަޑައިގަންނަވަމުން، ރަށެއްގެ އަހުލުވެރިބަޔަކާ ހަމަޔަށް ވަޑައިގެންނެވުނުހިނދު، އެރަށުގެ މީހުންގެ ކިބައިން ކާއެތިކޮޅަކަށް އެ ދެބޭކަލުން އެދިވަޑައިގަތެވެ. ފަހެ، އެއުރެން އެބޭކަލުންނަށް މެހުމާންދާރީ އަދާކުރުމަށް އިންކާރުކުޅައޫއެވެ. ދެން އެރަށުން ވެއްޓެންކައިރިވެފައިވާ ފާރެއް އެ ދެބޭކަލުން ދެކެވަޑައިގަތެވެ. ދެން އެބޭކަލަކު އެ ފާރު ތެދުކުރައްވައިފިއެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ކަލޭގެފާނު ބޭނުންފުޅުނަމަ، އެކަމަށް އުޖޫރައެއް ހިއްޕެވިދާނެއެވެ.","",""],["","","","قال هذا فراق بيني وبينك سأنبئك بتأويل ما لم تستطع عليه صبرا","އެބޭކަލަކު ވިދާޅުވިއެވެ. މިއީ ތިމަންކަލޭގެފާނާއި، ކަލޭގެފާނާ ދެމެދުގެ ވަކިވުމެވެ. ކަލޭގެފާނަށް އެކަންކަމުގެ މައްޗަށް ކެތްކުރެއްވުމަށް ކުޅަދާނަވެވަޑައިނުގެންނެވުނު ކަންތައްތަކުގެ ތަފްސީރު ތިމަންކަލޭގެފާނު، ކަލޭގެފާނަށް ކިޔައިދެއްވާ ހުށީމެވެ.","",""],["","","","أما السفينة فكانت لمساكين يعملون في البحر فأردت أن أعيبها وكان وراءهم ملك يأخذ كل سفينة غصبا","ނަވާމެދު ދަންނާށެވެ! ފަހެ، އެ ނައުވީ ކަނޑުގައި މަސައްކަތްކޮށްއުޅޭ މިސްކީނު ބަޔެއްގެ ނަވަކަށެވެ. ފަހެ، ތިމަންކަލޭގެފާނު އެ ނައު ހަލާކުކޮށްލެއްވުމަށް ގަސްދުކުރެއްވީ (ސަލާމަތުންވާ) ކޮންމެ ނަވެއް ޣަޞްބުން އަތުލާ ރަސްކަލަކު އެމީހުންގެ ފަހަތުގައިވާތީއެވެ.","",""],["","","","وأما الغلام فكان أبواه مؤمنين فخشينا أن يرهقهما طغيانا وكفرا","އަދި އެ ފިރިހެންކުއްޖާއާމެދު ދަންނާށެވެ! ފަހެ، އޭނާގެ މައިންބަފައިންވީ (ހެޔޮލަފާ) މުއުމިނުން ކަމުގައެވެ. ފަހެ، އެ ދެމީހުން އުރެދި ކާފިރުވާ ދަރަޖައަށް އެދެމީހުންނަށް އެ ކުއްޖާ އުނދަގޫކޮށް، އަނިޔާދީފާނެކަމަށް ތިމަންކަލޭގެފާނު ބިރުގަތީއެވެ.","",""],["","","","فأردنا أن يبدلهما ربهما خيرا منه زكاة وأقرب رحما","ފަހެ، ތިމަންކަލޭގެފާނު އެދިވަޑައިގަތީ، އެ ދެމީހުންގެ ވެރިރަސްކަލާނގެ، އެކުއްޖާއަށްވުރެ ހެޔޮވެގެންވާ ސާލިހު، އަދި އޯގާތެރިކަންބޮޑު ކުއްޖަކު އޭނާގެ ބަދަލުގައި އެދެމީހުންނަށް ދެއްވުމަށެވެ.","",""],["","","","وأما الجدار فكان لغلامين يتيمين في المدينة وكان تحته كنز لهما وكان أبوهما صالحا فأراد ربك أن يبلغا أشدهما ويستخرجا كنزهما رحمة من ربك وما فعلته عن أمري ذلك تأويل ما لم تسطع عليه صبرا","އަދި ފާރާމެދު ދަންނާށެވެ! ފަހެ، އެރަށުގައިވާ ޔަތީމު ދެކުދިންނަށް ލިބިގެންވާ ފާރެއްކަމުގައި އެ ފާރުވިއެވެ. އަދި އެ ފާރުގެ ދަށުގައި، އެދެކުދިންނަށް ޚަޒާނާއެއް ވިއެވެ. އަދި އެ ދެކުދިންގެ ބައްޕާއަކީ، ސާލިހު މީހެއް ކަމުގައިވެސްވިއެވެ. ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އިރާދަކުރެއްވީ، އެ ދެކުދިން ބޮޑުވެ، ފުރާފުރިހަމަވުމުން، އެ ދެކުދިންގެ ޚަޒާނާ، އެ ދެކުދިން ނެރުމަށެވެ. ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އޮތް ރަހުމަތެއްގެ ގޮތުންނެވެ. އަދި ތިމަންކަލޭގެފާނު އެކަންތައްކުރެއްވީ، ތިމަންކަލޭގެފާނުގެ އަމިއްލަ ރައުޔަކަށް ނޫނެވެ. މިއީ ކަލޭގެފާނަށް އެކަންކަމުގެ މައްޗަށް ކެތްކުރެއްވުމަށް ކުޅަދާނަވެވަޑައިނުގެންނެވުނު ކަންތަކުގެ ތަފްސީރެވެ.","",""],["","","","ويسألونك عن ذي القرنين قل سأتلو عليكم منه ذكرا","ޛުލްގަރުނައިނާމެދު އެއުރެން ކަލޭގެފާނާ ސުވާލުކުރެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭނާގެ ވާހަކައިން ތިމަންކަލޭގެފާނު، ތިޔަބައިމީހުންނަށް ކިޔައިދެއްވާ ހުށީމެވެ.","",""],["","","","إنا مكنا له في الأرض وآتيناه من كل شيء سببا","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އޭނާއަށް ބިމުގައި ކަންތައް ފަހިކޮށްދެއްވައި، ބާރުވެރިކޮށްދެއްވީމެވެ. އަދި ކޮންމެކަމަކުން، އޭނާއަށް މަގެއް ދެއްކެވީމެވެ.","",""],["","","","فأتبع سببا","ފަހެ، އޭނާ މަގަކުން ކުރިޔަށް ވަޑައިގަތެވެ.","",""],["","","","حتى إذا بلغ مغرب الشمس وجدها تغرب في عين حمئة ووجد عندها قوما قلنا يا ذا القرنين إما أن تعذب وإما أن تتخذ فيهم حسنا","އިރުއޮސްފުހޭ ތަނަށް އޭނާ ވަޑައިގަތުމަށް ދާނދެނެވެ. އެހިނދު ކަޅުކުލައިގެ ފެންގަނޑަކަށް އިރުއޮސްފުހޭތީ، އޭނާއަށް ފެނިވަޑައިގަތެވެ. އަދި އެތާނގެ ކައިރިން އޭނާއަށް ގައުމެއްގެ މީހުން ފެނިވަޑައިގަތެވެ. ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވީމެވެ. އޭ ޛުލްގަރުނައިނެވެ! އެހެންޏާ އެއުރެންނަށް ތިބާ އަދަބުދެއްވާށެވެ! އެހެންޏާ އެއުރެންނާމެދު އޯގާތެރިކޮށް ކަންތައް ކުރައްވާށެވެ!","",""],["","","","قال أما من ظلم فسوف نعذبه ثم يرد إلى ربه فيعذبه عذابا نكرا","އޭނާ ވިދާޅުވިއެވެ. އަނިޔާވެރިވީ މީހާއާމެދު (ދަންނާށެވެ!) ފަހެ، ނިކަންހުރެ އެމީހަކަށް އަހުރެމެން އަދަބު ދޭހުށީމުއެވެ. ދެން އޭނާގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް އޭނާ ރައްދުކުރައްވާހުށްޓެވެ. ފަހެ، އެކަލާނގެ އެމީހަކަށް، ގަދަފަދަވެގެންވާ އަޒާބެއް ދެއްވާހުށްޓެވެ.","",""],["","","","وأما من آمن وعمل صالحا فله جزاء الحسنى وسنقول له من أمرنا يسرا","އަދި އީމާންވެ، ސާލިހު ޢަމަލުކުރިމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް ހެޔޮ ޖަޒާހުށްޓެވެ. އަދި އެމީހަކަށް ތިމަންރަސްކަލާނގެ ފަސޭހަވެގެންވާގޮތެއް ދައްކަވާހުށީމެވެ.","",""],["","","","ثم أتبع سببا","ދެން އޭނާ އެހެންމަގަކުން ކުރިޔަށް ވަޑައިގަތެވެ.","",""],["","","","حتى إذا بلغ مطلع الشمس وجدها تطلع على قوم لم نجعل لهم من دونها سترا","އިރުއަރާތަނަށް އޭނާ ވަޑައިގަތުމަށް ދާނދެނެވެ. އެހިނދު، ގައުމެއްގެ މީހުންގެ މައްޗަށް އިރުއަރާތީ، އޭނާއަށް ފެނިވަޑައިގަތެވެ. އިރުގެ ހޫނުން ސަލާމަތްވާނެ އެއްވެސްކަހަލަ ނިވަލެއް ތިމަންރަސްކަލާނގެ އެއުރެންނަކަށް ނުލައްވަމެވެ.","",""],["","","","كذلك وقد أحطنا بما لديه خبرا","ކަންހުރީ އެފަދައިންނެވެ. ހަމަކަށަވަރުން، އޭނާގެ ކިބައިގައިވާހާ ކަމެއްގެ ޚަބަރު، ތިމަންރަސްކަލާނގެ މޮޅަށް ދެނެވޮޑިގެންވަމެވެ.","",""],["","","","ثم أتبع سببا","ދެން އޭނާ، އެހެން މަގަކުން ކުރިޔަށް ވަޑައިގަތެވެ.","",""],["","","","حتى إذا بلغ بين السدين وجد من دونهما قوما لا يكادون يفقهون قولا","ދެފަރުބަދަ ދޭތެރެއަށް އޭނާ ވަޑައިގަތުމަށް ދާނދެނެވެ. އެތާނގެ ކައިރިން އޭނާއަށް ބަޔަކުމީހުން ފެނިވަޑައިގަތެވެ. އެއްވެސް ބަހެއް (އުނދަގުލަކާލައިގެން މެނުވީ) އެއުރެންނަށް އެނގުމަކާ ގާތްވެސް ނުވެއެވެ.","",""],["","","","قالوا يا ذا القرنين إن يأجوج ومأجوج مفسدون في الأرض فهل نجعل لك خرجا على أن تجعل بيننا وبينهم سدا","އެއުރެން ބުނެފޫއެވެ. އޭ ޛުލްގަރުނައިނެވެ! ހަމަކަށަވަރުން، ޔައުޖޫޖު މައުޖޫޖު ބާގައިމީހުންނަކީ، ބިމުގައި ފަސާދަކޮށްއުޅޭ ބަޔެކެވެ. ފަހެ، ކަލޭގެފާނު ތިމަންމެންނާ އެއުރެންނާ ދެމެދުގައި ހުރަހެއް ލައްވައިދެއްވާންކަމަށް ކަލޭގެފާނަށް ތިމަންމެން ޖިޒީއެއް ދެންތޯއެވެ؟","",""],["","","","قال ما مكني فيه ربي خير فأعينوني بقوة أجعل بينكم وبينهم ردما","އޭނާ ވިދާޅުވިއެވެ. ތިމަންގެ ވެރިރަސްކަލާނގެ އެކަމުގައި ތިމަންނައަށް ދެއްވާފައިވާ ބާރު (ތިޔަ ޖިޒީއަށްވުރެ) މާރަނގަޅެވެ. ފަހެ، ތިޔަބައިމީހުން ބާރެއްލައިދީ، ތިމަންނާއާ ވާގިވެރިވާށެވެ! އޭރުން ތިޔަބައިމީހުންނާ އެއުރެންނާ ދެމެދު ހުރަހެއް ލައިދޭހުށީމެވެ.","",""],["","","","آتوني زبر الحديد حتى إذا ساوى بين الصدفين قال انفخوا حتى إذا جعله نارا قال آتوني أفرغ عليه قطرا","ތިމަންނާއަށް ދަގަނޑުގެ އެތިއެތިގަނޑު ގެނެސްދޭށެވެ! ދެން އެ ދެފަރުބަދަ ދޭތެރޭގައި އޮތްތަން އެއްވަރުވީހިނދު، އޭނާ ވިދާޅުވިއެވެ. އެ ދަގަނޑުތައް ދޮންވެ އަލިފާނަށް ވެއްޖައުމަށްދާނދެން ތިޔަބައިމީހުން ފުމޭށެވެ! އޭނާ ވިދާޅުވިއެވެ. ވިރުވާފައިވާ ރަންވަންލޮއި އޭގެމައްޗަށް އޮއްސައިލުމަށް ތިމަންނަޔަށް ގެނެސްދޭށެވެ.","",""],["","","","فما اسطاعوا أن يظهروه وما استطاعوا له نقبا","ފަހެ، އެ ހުރަހުގެ މަތިން އެއުރެންނަށް އެރުމަކަށް ކުޅަދާނައެއް ނުވިއެވެ. އަދި އެ ހުރަސް ފޫއަޅުވައިލުމަކަށްވެސް، އެއުރެންނަކަށް ކުޅަދާނައެއް ނުވިއެވެ.","",""],["","","","قال هذا رحمة من ربي فإذا جاء وعد ربي جعله دكاء وكان وعد ربي حقا","އޭނާ ވިދާޅުވިއެވެ. މިއީ ތިމަންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތު ންވާ ރަހުމަތެކެވެ. ފަހެ، ތިމަންގެ ވެރިރަސްކަލާނގެ ވައުދުފުޅު (ގެ ވަގުތު) އަތުވެއްޖެނަމަ، އެ ހުރަސް ކުނޑިކުނޑިވެގެން ހިނގައިދާހުށްޓެވެ. އަދި ތިމަންގެ ވެރިރަސްކަލާނގެ ވައުދުފުޅު، ހައްގު ތެދުކަމުގައިވިއެވެ.","",""],["","","","وتركنا بعضهم يومئذ يموج في بعض ونفخ في الصور فجمعناهم جمعا","އެދުވަހުން، ތިމަންރަސްކަލާނގެ އެއުރެންގެ އެއްބަޔަކު އަނެއްބަޔެއްގެ މައްޗަށް އުތުރިއަރާގޮތަށް ދޫކޮށްލައްވާހުށީމެވެ. އަދި ތާޅަފިލި ފުމެލައްވާހުށްޓެވެ. ފަހެ، އެހާރުން ތިމަންރަސްކަލާނގެ އެއުރެން އެންމެން (އެއްތަނަކަށް) އެއްކުރައްވާހުށީމެވެ.","",""],["","","","وعرضنا جهنم يومئذ للكافرين عرضا","އަދި އެދުވަހުން، ތިމަންރަސްކަލާނގެ ކާފިރުންނަށް ފެންނަގޮތަށް ނަރަކަ ހުށަހަޅުއްވާހުށީމެވެ.","",""],["","","","الذين كانت أعينهم في غطاء عن ذكري وكانوا لا يستطيعون سمعا","އެއުރެންނަކީ، ތިމަންރަސްކަލާނގެ ބާވައިލެއްވި ގުރްއާން ފިޔަވައި އެއުރެންގެ ލޯތައް ފަރުދާވެގެންވާ މީހުންނެވެ. އަދި (އެ ގުރްއާން) އަޑުއެހުމަކަށްވެސް އެއުރެންނަކަށް ކުޅަދާނަވެގެނެއް ނުވެތެވެ.","",""],["","","","أفحسب الذين كفروا أن يتخذوا عبادي من دوني أولياء إنا أعتدنا جهنم للكافرين نزلا","ތިމަންރަސްކަލާނގެ އަޅުންނީ ތިމަންރަސްކަލާނގެ ފިޔަވައި ވާގިވެރިން ކަމުގައި، ކާފިރުވި މީހުން ހިފިހިފުން އެއީ، ތިމަންރަސްކަލާނގެ އަޒާބުން އެއުރެން ސަލާމަތްކޮށްދޭނޭ ކަމެއްކަމުގައި އެއުރެން ހީކުރީހެއްޔެވެ؟ ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ނަރަކަ ތައްޔާރުކުރެއްވީ، ކާފިރުން ތިބެނިވި ތަނެއްކަމުގައެވެ.","",""],["","","","قل هل ننبئكم بالأخسرين أعمالا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ޢަމަލުތައް އެންމެބޮޑަށް ގެއްލެނިވެގެންވާ މީހުންގެ ޚަބަރު، ތިޔަބައިމީހުންނަށް ތިމަންކަލޭގެފާނު އަންގަވައިދެއްވަން ހެއްޔެވެ؟","",""],["","","","الذين ضل سعيهم في الحياة الدنيا وهم يحسبون أنهم يحسنون صنعا","އެއުރެންނަކީ ދުނިޔަވީ ހަޔާތުގައި، އެއުރެންގެ ޢަމަލުތައް ބާތިލުވެ، ގެއްލިފައިވާ މީހުންނެވެ. އަދި އެއުރެން ރަނގަޅަށް ކަންތައްކުރާކަމަށް އެއުރެން ހީކުރެތެވެ.","",""],["","","","أولئك الذين كفروا بآيات ربهم ولقائه فحبطت أعمالهم فلا نقيم لهم يوم القيامة وزنا","އެއުރެންނަކީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ އާޔަތް ތަކަށާއި، އެކަލާނގެއާ ބައްދަލުވާންޖެހޭނެކަމަށް ކާފިރުވި މީހުންނެވެ. ފަހެ، އެއުރެންގެ ޢަމަލުތައް ބާތިލު ވެފައިވެއެވެ. ފަހެ، ގިޔާމަތް ދުވަހުން އެއުރެންނަކަށް (އެބަހީ: އެއުރެންގެ ޢަމަލު ތަކަކަށް) ތިމަންރަސްކަލާނގެ އެއްވެސް ބަރުދަނެއް ނުލައްވާހުށީމެވެ.","",""],["","","","ذلك جزاؤهم جهنم بما كفروا واتخذوا آياتي ورسلي هزوا","އެއީ އެއުރެންގެ ޖަޒާއެއްކަމުގައިވާ ނަރަކައެވެ. އެއީ އެއުރެން ކާފިރުވެ އަދި ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާއި، ތިމަންރަސްކަލާނގެ ރަސޫލުންނީ ފުރައްސާރައެއް ކަމުގައި ހެދިކަމަށްޓަކައެވެ.","",""],["","","","إن الذين آمنوا وعملوا الصالحات كانت لهم جنات الفردوس نزلا","ހަމަކަށަވަރުން، އީމާންވެ، ސާލިހު ޢަމަލުތައް ކުޅަމީހުންނަށް އެއުރެން ތިބެނިވި ތަނެއްކަމުގައި، ފިރުދައުސް އޭ ކިއުނު ސުވަރުގެތައް ވެއެވެ.","",""],["","","","خالدين فيها لا يبغون عنها حولا","އެއުރެން އެތަންފިޔަވައި، އެހެންފަރާތަކަށް އެނބުރިދިއުމަށް ނޭދި، އެތާނގައި ދެމިތިބޭ ޙާލު ގައެވެ.","",""],["","","","قل لو كان البحر مدادا لكلمات ربي لنفد البحر قبل أن تنفد كلمات ربي ولو جئنا بمثله مددا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ކަލިމަ ފުޅުތަކަށް ދަވާދެއްކަމުގައި ކަނޑުވީނަމަ، ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ކަލިމަފުޅުތައް (ލިޔެ) ހުސްވުމުގެކުރިން ކަނޑު ހުސްވެއްޖައީހެވެ. ތިމަންރަސްކަލާނގެ އެފަދަ އެހެންކަނޑެއް އިތުރަށް ގެނެސްދެއްވިނަމަވެހެވެ.","",""],["","","","قل إنما أنا بشر مثلكم يوحى إلي أنما إلهكم إله واحد فمن كان يرجو لقاء ربه فليعمل عملا صالحا ولا يشرك بعبادة ربه أحدا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނު ވާކަންކަށަވަރީ، ތިޔަބައިމީހުންކަހަލަ އާދަމުގެދަރިޔަކު ކަމުގައެވެ. ތިމަންކަލޭގެފާނަށް ވަހީ އިއްވަވަނީ، ތިޔަބައިމީހުންގެ އިލާހަކީ، އެއް އިލާހެއް ކަމުގައެވެ. ފަހެ، އެމީހެއްގެ ވެރިރަސްކަލާނގެއާ ބައްދަލުވުމަށް އެދޭމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާ ސާލިހު ޢަމަލުން ޢަމަލުކުރާ ހުށިކަމެވެ! އަދި އެމީހާގެ ވެރިރަސްކަލާނގެއަށް އަޅުކަންކުރުމުގައި، އެއްވެސްމީހަކު ބައިވެރި ނުކުރާހުށިކަމެވެ!","",""],["","","","بسم الله الرحمن الرحيم كهيعص","ك هـ ى ع ص (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","ذكر رحمت ربك عبده زكريا","މިއީ ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެކަލާނގެ އަޅާ ޒަކަރިއްޔާގެފާނަށް ލެއްވި ރަހުމަތްގެ ވާހަކައެވެ.","",""],["","","","إذ نادى ربه نداء خفيا","އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް، އެކަލޭގެފާނު ސިއްރުގައި ދުއާކުރެއްވި ހިނދެވެ.","",""],["","","","قال رب إني وهن العظم مني واشتعل الرأس شيبا ولم أكن بدعائك رب شقيا","އެކަލޭގެފާނު ދެންނެވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، އަޅުގެ ކަށިތައް ބަލިވެ ނިކަމެތިވެއްޖެއެވެ. އަދި ބޮލުގެ އިސްތަށިތައްވެސް އެކަށް ނުރަވެއްޖެއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! މިއަޅާ އިބަރަސްކަލާނގެއަށް ކޮށްފި ދުއާއަކުން، މިއަޅާ އަބާއްޖަވެރިޔަކު ކަމުގައި ނުވަމެވެ.","",""],["","","","وإني خفت الموالي من ورائي وكانت امرأتي عاقرا فهب لي من لدنك وليا","އަދި ހަމަކަށަވަރުން، އަޅުގެފަހަށް، އަޅުގެ ތިމާގެމީހުން (ދީންގެ ކަންތައް ބެލެހެއްޓުމުގައި) ކަންތައް ކުރާނޭގޮތާމެދު އަޅު ބިރުގަނެއެވެ. އަޅުގެ އަނބިމީހާއަކީ، ދަރިމައިނުވާ އަންހެނެކެވެ. ފަހެ، އިބަރަސްކަލާނގެ ރަހުމަތްފުޅުން މިއަޅާއަށް ވާރިޘަކު ދެއްވައިފާނދޭވެ!","",""],["","","","يرثني ويرث من آل يعقوب واجعله رب رضيا","ތިމަންއަޅާއާއި، ޔައުގޫބުގެފާނުގެ އާލުވެރިންގެ ކިބައިން ވާރުތަވާނޭ ވާރިޘެކެވެ. އަދި މިއަޅާގެ ވެރިރަސްކަލާކޮ! އިބަރަސްކަލާނގެ ރުހިވޮޑިގެންވާ އަޅަކު ކަމުގައި، އޭނާ ލައްވައިފާނދޭވެ!","",""],["","","","يا زكريا إنا نبشرك بغلام اسمه يحيى لم نجعل له من قبل سميا","އޭ ޒަކަރިއްޔާގެފާނެވެ! ހަމަކަށަވަރުން، ފިރިހެންދަރިޔަކު ލިބޭނެކަމުގެ އުފާވެރި ޚަބަރު ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނަށް ދެއްވަމެވެ. އޭނާގެ ނަމަކީ، ޔަޙްޔާއެވެ. މީގެކުރިން އޭނާގެ ނަމުން ނަންކިޔޭ މީހަކު ތިމަންރަސްކަލާނގެ ނުލައްވަމެވެ.","",""],["","","","قال رب أنى يكون لي غلام وكانت امرأتي عاقرا وقد بلغت من الكبر عتيا","އެކަލޭގެފާނު ދެންނެވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! މިއަޅާއަށް ކުއްޖަކު ލިބޭނީ ކިހިނަކުންތޯއެވެ؟ އަޅުގެ އަނބިމީހާއަކީ، ދަރިމައިނުވާ އަންހެނެކެވެ. އަދި އަޅާވެސް މިހުރީ، މުސްކުޅިކަމުގެ ނިހާޔަތަށް ފޯރާފައެވެ.","",""],["","","","قال كذلك قال ربك هو علي هين وقد خلقتك من قبل ولم تك شيئا","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ކަންހުރީ އެފަދައިންނެވެ. ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ވަހީކުރެއްވިއެވެ. އެއީ ތިމަންރަސްކަލާނގެއަށް ދާދިފަސޭހަ ކަމެކެވެ. މީގެކުރިން ކަލޭގެފާނަކީ، މައުޖޫދު ވެގެންވާ އެއްޗެއްކަމުގައި ނުވާ ޙާލު، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ހެއްދެވީމެވެ.","",""],["","","","قال رب اجعل لي آية قال آيتك ألا تكلم الناس ثلاث ليال سويا","އެކަލޭގެފާނު ދެންނެވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! އަޅާއަށް އަލާމަތެއް ލައްވައިފާނދޭވެ! އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ކަލޭގެފާނަށް އޮތް އަލާމަތަކީ ކަލޭގެފާނަށް (ސަލާމަތުން ހުންނަވައިމެ) ފުރިހަމަ ތިންރޭ ވަންދެން މީސްތަކުންނާ ވާހަކަ ނުދެއްކެވޭގޮތްވުމެވެ.","",""],["","","","فخرج على قومه من المحراب فأوحى إليهم أن سبحوا بكرة وعشيا","ފަހެ، އެކަލޭގެފާނު، ނަމާދުކުރައްވާތަނުން އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ގާތަށް ނުކުމެވަޑައިގަތެވެ. ދެން ހެނދުނާއި، ހަވީރު، ތަސްބީހަ ކިޔަވައި އުޅުމަށް އެއުރެންނަށް އިޝާރަތުން އެންގެވިއެވެ.","",""],["","","","يا يحيى خذ الكتاب بقوة وآتيناه الحكم صبيا","އޭ ޔަޙްޔާގެފާނެވެ! ކަލޭގެފާނު ފޮތުގައި ބާރަށް ހިފަހައްޓަވާށެވެ! ތިމަންރަސްކަލާނގެ، އެކަލޭގެފާނަށް ތުއްޕުޅުއިރު ހިކުމަތް ދެއްވީމެވެ.","",""],["","","","وحنانا من لدنا وزكاة وكان تقيا","އަދި ތިމަންރަސްކަލާނގެ ހަޒުރަތުން އޯގާވެރިކަމާއި، ތާހިރު ކަން އެކަލޭގެފާނަށް ދެއްވީމެވެ. އަދި އެކަލޭގެފާނު ތަގުވާވެރިޔަކު ކަމުގައިވިއެވެ.","",""],["","","","وبرا بوالديه ولم يكن جبارا عصيا","އަދި އެކަލޭގެފާނުގެ މައިބަފައިކަލުންނަށް ހެޔޮކޮށް ހިއްތަވާ ބޭކަލަކު ކަމުގައިވިއެވެ. އަދި ނުކިޔަމަންތެރި، ޖައްބާރަކު ކަމުގައި އެކަލޭގެފާނު ނުވެއެވެ.","",""],["","","","وسلام عليه يوم ولد ويوم يموت ويوم يبعث حيا","އަދި އެކަލޭގެފާނު އުފަންވި ދުވަހުގައްޔާއި، އަވަހާރަވާ ދުވަހުގައްޔާއި، އަލުން ދިރުއްވައި ފޮނުއްވާ ދުވަހުގައި، އެކަލޭގެފާނުގެ މައްޗަށް ސަލާމް ހުށްޓެވެ.","",""],["","","","واذكر في الكتاب مريم إذ انتبذت من أهلها مكانا شرقيا","އަދި ކަލޭގެފާނު މި ފޮތުން މަރިޔަމްގެފާނުގެ ވާހަކަ ކިޔައިދެއްވާށެވެ! އެކަމަނާ، އެކަމަނާގެ އަހުލުވެރިންގެ ކިބައިން އެކަހެރިވެ، އިރުމަތީ ފަރާތުގައިވާ ތަނަކަށް ވަޑައިގަތްހިނދެވެ.","",""],["","","","فاتخذت من دونهم حجابا فأرسلنا إليها روحنا فتمثل لها بشرا سويا","ފަހެ، އެއުރެންގެ ކިބައިން އެކަމަނާ ނިވައިވެ، ފަރުދާވެވަޑައިގަތެވެ. ދެން ތިމަންރަސްކަލާނގެ ވަހީގެ މަލާއިކަތާ، އެކަމަނާގެ އަރިހަށް ފޮނުއްވީމެވެ. އަދި އެ މަލާއިކަތާ ފުރިހަމަ އިންސާނެއްގެ ސިފައިގައި، އެކަމަނާއަށް ފާޅުވިއެވެ.","",""],["","","","قالت إني أعوذ بالرحمن منك إن كنت تقيا","އެކަމަނާ ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިބާގެ ކިބައިން ސަލާމަތް ކުރެއްވުމަށް، ރަޙްމާންވަންތަ ރަސްކަލާނގެ ހަޒުރަތުން އަހުރެން ވާގިއެދި، ރައްކާތެރިކަން ލިބިގަންނަމެވެ. ތިބާއަކީ (ﷲއަށް) ބިރުވެތިވާ މީހަކު ކަމުގައި ވަނީނަމައެވެ.","",""],["","","","قال إنما أنا رسول ربك لأهب لك غلاما زكيا","އެ މަލާއިކަތާ ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިމަންނާއަކީ، ކަމަނާގެ ވެރިރަސްކަލާނގެ ފޮނުއްވި ރަސޫލަކީމެވެ. ހެޔޮލަފާ، ސާލިހު ފިރިހެން ދަރިކަލަކު ކަމަނާއަށް ދެއްވުމަށްޓަކައެވެ.","",""],["","","","قالت أنى يكون لي غلام ولم يمسسني بشر ولم أك بغيا","އެކަމަނާ ވިދާޅުވިއެވެ. ތިމަންނާއަށް ދަރިއަކު ލިބޭހުށީ ކޮންފަދައަކުންތޯއެވެ؟ ތިމަންގެ ގައިގައި އެއްވެސް އާދަމުގެދަރިޔަކު ބީހިފައެއްނުވެއެވެ. އަދި ތިމަންނާއީ، ކަސްބީއަކު ކަމުގައިވެސް ނުވަމެވެ.","",""],["","","","قال كذلك قال ربك هو علي هين ولنجعله آية للناس ورحمة منا وكان أمرا مقضيا","އެ މަލާއިކަތާ ވިދާޅުވިއެވެ. ކަންހުރީ އެފަދައިންނެވެ. ކަމަނާގެ ވެރިރަސްކަލާނގެ ވަހީކުރެއްވިއެވެ. އެއީ ތިމަންރަސްކަލާނގެއަށް ދާދިފަސޭހަ ކަމެކެވެ. އަދި ތިމަންރަސްކަލާނގެ ހަޒުރަތުން މީސްތަކުންނަށް ފޮނުއްވި އާޔަތެއް ކަމުގައްޔާއި، ރަހުމަތެއްކަމުގައި، އެ ދަރިކަލުން ލެއްވުމަށްޓަކައެވެ. ކަނޑައެޅި ނިމިފައިވާ ކަމެއްކަމުގައި އެކަންތައްވިއެވެ.","",""],["","","","فحملته فانتبذت به مكانا قصيا","ފަހެ، އެ ދަރިކަލުންނާއިގެން އެކަމަނާ އާލާސްވެ އިންނަވައި، ދުރުގައިވާ ތަނަކަށް އެ ދަރިކަލުންނާއިގެން އެކަމަނާ ވަޑައިގަތެވެ.","",""],["","","","فأجاءها المخاض إلى جذع النخلة قالت يا ليتني مت قبل هذا وكنت نسيا منسيا","ދެން އެކަމަނާއަށް ރައްކާވުމުގެ ވޭންވަރު އައުމުން، ކަދުރު ރުކެއްގެ ގަސްގަނޑުގައި ލެނގިވަޑައިގެން އިންނަވަންޖެހުނެވެ. އެކަމަނާ ވިދާޅުވިއެވެ. އޭ ސަހަރޯއެވެ! މިކަންޖެހުމުގެ ކުރީގައި އަހުރެން މަރުވެ، ހަނދާންނެތިވެ، ނަންވެސް ފިލައިދިޔަނަމަ ކޮންފަދަހެއްޔެވެ!","",""],["","","","فناداها من تحتها ألا تحزني قد جعل ربك تحتك سريا","ދެން އެކަމަނާ (އޮންނެވިތާނ) ގެ ދަށުން އެކަމަނާއަށް މަލާއިކަތާ ގޮވައިލެއްވިއެވެ. ހިތާމަނުކުރައްވާށެވެ! ހަމަކަށަވަރުން، ކަމަނާގެ ވެރިރަސްކަލާނގެ، ކަމަނާ (ތިޔައޮންނެވިތާނ) ގެ ދަށުން ފެންއާރެއް ލެއްވިއެވެ.","",""],["","","","وهزي إليك بجذع النخلة تساقط عليك رطبا جنيا","އަދި ކަމަނާއާ ދިމާޔަށް ކަދުރުރުކުގެ ގަސްގަނޑު ހަލުވައިލައްވާށެވެ! އޭރުން ދޮންވެ ފައްކާވެފައިވާ ކަދުރުތައް، ކަމަނާގެ އަރިހަށް ފައިބާނެތެވެ.","",""],["","","","فكلي واشربي وقري عينا فإما ترين من البشر أحدا فقولي إني نذرت للرحمن صوما فلن أكلم اليوم إنسيا","ފަހެ، ކަމަނާ ފަރީއްކުޅުއްވައި، ފެންފޮދު ހިއްޕަވައި، އަދި ހިތްޕުޅު ހަމަޖައްސަވާށެވެ! ފަހެ، އިންސާނުންކުރެ އެއްވެސްމީހަކު ކަމަނާއަށް ފެނިވަޑައިގެންފިނަމަ، ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ރަޙްމާންވަންތަ ރަސްކަލާނގެއަށްޓަކައި، ރޯދައަށް ހުރުމަށް (އެބަހީ: ހަނުހުރުމަށް) އަހުރެން ނަދުރުގެންފީމެވެ. ފަހެ، މިއަދު އަހުރެން އެއްވެސް އިންސާނަކާ ވާހަކައެއް ނުދައްކާހުށީމެވެ.","",""],["","","","فأتت به قومها تحمله قالوا يا مريم لقد جئت شيئا فريا","ފަހެ، އެކަމަނާގެ ގައުމުގެމީހުންގެ ގާތަށް އެ ދަރިކަލުން އުރުވަޑުވައިގެން އެކަމަނާ ވަޑައިގަތެވެ. އެއުރެން ބުނޫއެވެ. އޭ މަރިޔަމްގެފާނެވެ! ހަމަކަށަވަރުން، ކަމަނާ ތިޔަވަޑައިގަތީ ވަރަށްބޮޑު ނުބައިކަމަކާއިގެންނެވެ.","",""],["","","","يا أخت هارون ما كان أبوك امرأ سوء وما كانت أمك بغيا","އޭ ހާރޫނުގެ އުޚްތާއެވެ! ކަމަނާގެ ބައްޕާއަކީ، ނުބައިމީހެއްކަމުގައި ނުވެތެވެ. އަދި ކަމަނާގެ މަންމާއަކީ، ކަސްބީއަކު ކަމުގައިވެސް ނުމެވޭމެއެވެ.","",""],["","","","فأشارت إليه قالوا كيف نكلم من كان في المهد صبيا","ފަހެ، އެކަމަނާ އެ ދަރިކަލުންނަށް އިޝާރަތް ކޮށްލެއްވިއެވެ. އެއުރެން ބުނެފޫއެވެ. ޅަފަތުގެ ދާނުގައިވާ ޅަކުއްޖަކާ ތިމަންމެން ވާހަކަދައްކާނީ ކިހިނަކުންހެއްޔެވެ؟","",""],["","","","قال إني عبد الله آتاني الكتاب وجعلني نبيا","އެ ދަރިކަލުން ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، އަހުރެންނަކީ، ﷲގެ އަޅަކީމެވެ. އެކަލާނގެ މިއަޅާޔަށް ފޮތް ދެއްވިއެވެ. އަދި ނަބިއްޔަކު ކަމުގައި މިއަޅާ ލެއްވިއެވެ.","",""],["","","","وجعلني مباركا أين ما كنت وأوصاني بالصلاة والزكاة ما دمت حيا","އަދި މިއަޅާ ކޮންމެ ތަނެއްގައި ވީނަމަވެސް، ބަރަކާތް ލައްވާފައިވާ އަޅަކު ކަމުގައި މިއަޅާ ލެއްވިއެވެ. އަދި މިއަޅާ ދިރިހުރިހާ ހިނދަކު، ނަމާދުކުރުމަށާއި، ޒަކާތް ދިނުމަށް، އެކަލާނގެ މިއަޅާޔަށް ވަސިއްޔަތްކުރެއްވިއެވެ.","",""],["","","","وبرا بوالدتي ولم يجعلني جبارا شقيا","އަދި މިއަޅާގެ މަންމާއަށް ހެޔޮކޮށް ހިތާމީހަކު ކަމުގައިވުމަށްވެހެވެ. އަދި މިއަޅާޔަކީ އަބާއްޖަވެރި، ޖައްބާރަކު ކަމުގައި ނުލައްވަތެވެ.","",""],["","","","والسلام علي يوم ولدت ويوم أموت ويوم أبعث حيا","މިއަޅާ އުފަންވިދުވަހުގައްޔާއި، މަރުވާދުވަހުގައްޔާއި، އަލުން ދިރުއްވައި (މަހުޝަރަށް) ފޮނުއްވާދުވަހުގައި، މިއަޅާގެ މައްޗަށް ސަލާމް ހުށްޓެވެ.","",""],["","","","ذلك عيسى ابن مريم قول الحق الذي فيه يمترون","އެއީ މަރިޔަމްގެފާނުގެ ދަރިކަލުން ޢީސާގެފާނެވެ. (މިއީ) އެއުރެން އެބަސްފުޅާމެދު ޝައްކުކުރާ، ހައްގު ތެދުބަސްފުޅެވެ.","",""],["","","","ما كان لله أن يتخذ من ولد سبحانه إذا قضى أمرا فإنما يقول له كن فيكون","ދަރިކަލަކު ހިއްޕެވުން އެއީ، ﷲއަށް އެކަށީގެންވާ ކަމެއްނޫނެވެ. އެކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! އެކަލާނގެ ކަމަކަށް ނިޔާކުރައްވައިފިހިނދު، އެކަމަކަށް ވަހީކުރައްވާކަން ކަށަވަރީ، [ވާށޭ] އެވެ! ދެން އެކަމެއް ވެދެތެވެ.","",""],["","","","وإن الله ربي وربكم فاعبدوه هذا صراط مستقيم","ހަމަކަށަވަރުން، ﷲއީ، ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއެވެ. އަދި ތިޔަބައިމީހުންގެވެސް ވެރިރަސްކަލާނގެއެވެ. ފަހެ، ތިޔަބައިމީހުން އެކަލާނގެއަށް އަޅުކަންކުރާށެވެ! މިއީ ސީދާވެގެންވާ ތެދުމަގެވެ.","",""],["","","","فاختلف الأحزاب من بينهم فويل للذين كفروا من مشهد يوم عظيم","ފަހެ، އެއުރެންގެ އެކި ޖަމާއަތްތަކުގެ މެދުގައި ޚިލާފު އުފެދުނެވެ. ފަހެ، ބޮޑުވެގެންވާ ދުވަހެއްގެ (ބިރުވެރިކަން) ދެކޭހިނދު، ކާފިރު ވީ މީހުންނަށް ހަލާކާއި ގެއްލުންހުށްޓެވެ.","",""],["","","","أسمع بهم وأبصر يوم يأتوننا لكن الظالمون اليوم في ضلال مبين","އެއުރެން ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް އަންނަދުވަހު، އެއުރެންގެ އިވުމާއި ފެނުމުގެ ސާފުކަން ބޮޑުކަމާއެވެ! އެހެނެއްކަމަކު، އަނިޔާވެރިވީ މީހުން މިއަދުވަނީ، ފާޅުވެ ބަޔާން ވެގެންވާ މަގުފުރެދުމެއްގައެވެ.","",""],["","","","وأنذرهم يوم الحسرة إذ قضي الأمر وهم في غفلة وهم لا يؤمنون","ހުރިހާކަމެއް ނިޔާކުރައްވާހިނދު (އެއުރެންނަށް އޮތް) ހިތާމައިގެ ދުވަހާމެދު، ކަލޭގެފާނު އެއުރެންނަށް އިންޒާރުކުރައްވާށެވެ! (އެދުވަހާމެދު) އެއުރެންވަނީ ޣާފިލުކަމެއްގެ ތެރޭގައެވެ. އަދި އެއުރެން އީމާނެއް ނުމެވޭމެއެވެ.","",""],["","","","إنا نحن نرث الأرض ومن عليها وإلينا يرجعون","ހަމަކަށަވަރުން، ބިމާއި، ބިމުގައިވާހާ ބަޔަކު ވާރުތަވެ މަލަކަ ވެގެންވަނީ، ތިމަންރަސްކަލާނގެއަށެވެ. އަދި އެއުރެން ރުޖޫއަކުރައްވާހުށީ، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","واذكر في الكتاب إبراهيم إنه كان صديقا نبيا","ކަލޭގެފާނު މިފޮތުން އިބްރާހީމްގެފާނުގެ ވާހަކަ ކިޔައިދެއްވާށެވެ! ހަމަކަށަވަރުން އެކަލޭގެފާނަކީ، ތެދުވެރިކަންބޮޑު ނަބިއްޔަކު ކަމުގައިވިއެވެ.","",""],["","","","إذ قال لأبيه يا أبت لم تعبد ما لا يسمع ولا يبصر ولا يغني عنك شيئا","އެކަލޭގެފާނުގެ ބައްޕައަށް އެކަލޭގެފާނު ވިދާޅުވިހިނދެވެ. އޭ ބައްޕާއެވެ! އެއްވެސް އަޑެއް ނީވޭ، އެއްވެސް އެއްޗެއް ނުފެންނަ، އަދި ބައްޕައަށް އެއްވެސް ކަމެއް ފުއްދައިނުދޭ އެއްޗަކަށް، ބައްޕަ އަޅުކަންކުރަނީ ކީއްވެގެންހެއްޔެވެ؟","",""],["","","","يا أبت إني قد جاءني من العلم ما لم يأتك فاتبعني أهدك صراطا سويا","އޭ ބައްޕާއެވެ! އިލްމުގެ ތެރެއިން، ބައްޕައަށް އައިސްފައިނުވާ އިލްމު، ތިމަންނާއަށް ހަމަކަށަވަރުން، އައިސްފައިވެއެވެ. ފަހެ، ތިމަންނާއަށް ބައްޕަ ތަބާ ވާށެވެ! އޭރުން ބައްޕައަށް ސީދާވެގެންވާ ތެދުމަގަކަށް މަގުދައްކާހުށީމެވެ.","",""],["","","","يا أبت لا تعبد الشيطان إن الشيطان كان للرحمن عصيا","އޭ ބައްޕާއެވެ! ޝައިތާނާއަށް އަޅުކަން ނުކުރާށެވެ! ހަމަކަށަވަރުން، ރަޙްމާންވަންތަ ރަސްކަލާނގެއަށް ނުކިޔަމަންތެރިޔެއް ކަމުގައި ޝައިތާނާ ވިއެވެ.","",""],["","","","يا أبت إني أخاف أن يمسك عذاب من الرحمن فتكون للشيطان وليا","އޭ ބައްޕާއެވެ! ހަމަކަށަވަރުން، ރަޙްމާންވަންތަ ރަސްކަލާނގެ ހަޒުރަތުން އަޒާބެއް އައިސް، ބައްޕައަށް ޖެހިދާނެކަމަށް އަހުރެން ބިރުގަނެއެވެ. އޭރުން ބައްޕަ ވާހުށީ، ޝައިތާނާގެ އެހީތެރިޔެއް ކަމުގައެވެ.","",""],["","","","قال أراغب أنت عن آلهتي يا إبراهيم لئن لم تنته لأرجمنك واهجرني مليا","އޭނާ ބުންޏެވެ. އޭ އިބްރާހީމެވެ! ތިމަންގެ އިލާހު ންތަކަށް ތިބާ ނުރުހެނީހެއްޔެވެ؟ ތިބާ ތިޔަކަންތައް ނުހުއްޓައިފިނަމަ، ހަމަކަށަވަރުން، އަހުރެން ގަލުން ތަޅައި، ތިބާ މަރައިފާހުށީމެވެ. އަދި ދިގުމުއްދަތަކަށް، އަހުރެންނާ ވަކިވާށެވެ!","",""],["","","","قال سلام عليك سأستغفر لك ربي إنه كان بي حفيا","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ބައްޕަގެ މައްޗަށް ސަލާމް ހުށްޓެވެ! ބައްޕައަށް ފާފަފުއްސެވުން އެދި، އަޅުގެ ވެރިރަސްކަލާނގެއަށް ދުއާކުރާހުށީމެވެ. ހަމަކަށަވަރުން، އަޅުގެމައްޗަށް ނުހަނު އޯގާވަންތަ ކަލަކު ކަމުގައި، އެކަލާނގެ ވޮޑިގެންވެއެވެ.","",""],["","","","وأعتزلكم وما تدعون من دون الله وأدعو ربي عسى ألا أكون بدعاء ربي شقيا","އަދި ތިޔަބައިމީހުންނާއި ﷲ ފިޔަވައި ތިޔަބައިމީހުން އަޅުކަންކުރާ ތަކެއްޗާ، އަހުރެން ވަކިވާހުށީމެވެ. އަދި އަހުރެންގެ ވެރިރަސްކަލާނގެއަށް އަޅުކަންކުރާހުށީމެވެ. އަހުރެންގެ ވެރިރަސްކަލާނގެއަށް އަޅުކަންކުރުމުން އަބާއްޖަވެރިޔަކު ކަމުގައި އަހުރެން ނުވާށިއެވެ.","",""],["","","","فلما اعتزلهم وما يعبدون من دون الله وهبنا له إسحاق ويعقوب وكلا جعلنا نبيا","ފަހެ، އެކަލޭގެފާނު، އެއުރެންނާއި، ﷲ ފިޔަވައި އެއުރެން އަޅުކަންކުރާ ތަކެއްޗާ ވަކިވެވަޑައިގަތްހިނދު، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް، އިސްޙާގުގެފާނާއި، ޔައުގޫބުގެފާނު ދެއްވީމެވެ. އަދި އެއިން ކޮންމެ ބޭކަލަކީ ނަބިއްޔަކު ކަމުގައި ލެއްވީމެވެ.","",""],["","","","ووهبنا لهم من رحمتنا وجعلنا لهم لسان صدق عليا","އަދި އެބޭކަލުންނަށް، ތިމަންރަސްކަލާނގެ ރަހުމަތްގެތެރެއިން ދެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ، އެބޭކަލުންނަށް (އަންނަނިވި ޖީލުތަކުގެ ދޫމަތީގައި) މަތިވެރިވެގެންވާ ރިވެތި ނަން ލެއްވީމެވެ.","",""],["","","","واذكر في الكتاب موسى إنه كان مخلصا وكان رسولا نبيا","ކަލޭގެފާނު މިފޮތުން މޫސާގެފާނުގެ ވާހަކަ ކިޔައިދެއްވާށެވެ! ހަމަކަށަވަރުން، ޚިޔާރުކުރައްވާފައިވާ ބޭކަލަކު ކަމުގައި އެކަލޭގެފާނު ވިއެވެ. އަދި ރަސޫލަކު ކަމުގައްޔާއި، ނަބިއްޔަކު ކަމުގައި އެކަލޭގެފާނު ވިއެވެ.","",""],["","","","وناديناه من جانب الطور الأيمن وقربناه نجيا","އަދި ތިމަންރަސްކަލާނގެ ޠޫރު ފަރުބަދައިގެ ކަނާތްފަރާތުން އެކަލޭގެފާނަށް ނިދާ އިއްވެވީމެވެ. އަދި ބަސް ވަހީކުރެއްވުމަށްޓަކައި އެކަލޭގެފާނު ކުއްތަން ކުރެއްވީމެވެ.","",""],["","","","ووهبنا له من رحمتنا أخاه هارون نبيا","އަދި ތިމަންރަސްކަލާނގެ ރަހުމަތް ވަންތަކަމުން، އެކަލޭގެފާނުގެ އަޚު، ހާރޫނުގެފާނު ނަބިއްޔަކު ކަމުގައި، އެކަލޭގެފާނަށް ދެއްވީމެވެ.","",""],["","","","واذكر في الكتاب إسماعيل إنه كان صادق الوعد وكان رسولا نبيا","ކަލޭގެފާނު މި ފޮތުން އިސްމާޢީލުގެފާނުގެ ވާހަކަ ކިޔައިދެއްވާށެވެ! ހަމަކަށަވަރުން، ވައުދު ފުއްދުމުގައި ތެދުވެރިޔަކު ކަމުގައި އެކަލޭގެފާނު ވިއެވެ. އަދި ރަސޫލަކު ކަމުގައްޔާއި، ނަބިއްޔަކު ކަމުގައި އެކަލޭގެފާނުވިއެވެ.","",""],["","","","وكان يأمر أهله بالصلاة والزكاة وكان عند ربه مرضيا","އަދި އެކަލޭގެފާނުގެ އަހުލުވެރިންނަށް، ނަމާދު ކުރުމަށާއި، ޒަކާތް ދީ އުޅުމަށް، އެކަލޭގެފާނު އަމުރުކުރައްވާ ކަމުގައިވިއެވެ. އަދި އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި، ރުއްސުންލައްވާފައިވާ ބޭކަލަކު ކަމުގައި އެކަލޭގެފާނުވިއެވެ.","",""],["","","","واذكر في الكتاب إدريس إنه كان صديقا نبيا","ކަލޭގެފާނު މިފޮތުން އިދްރީސްގެފާނުގެ ވާހަކަ ކިޔައިދެއްވާށެވެ! ހަމަކަށަވަރުން، އެކަލޭގެފާނަކީ، ތެދުވެރިކަން ބޮޑު ނަބިއްޔަކު ކަމުގައިވިއެވެ.","",""],["","","","ورفعناه مكانا عليا","އަދި ތިމަންރަސްކަލާނގެ، އެކަލޭގެފާނު މަތިވެރިވެގެންވާ މަގާމަކަށް އުފުއްލެވީމެވެ.","",""],["","","","أولئك الذين أنعم الله عليهم من النبيين من ذرية آدم وممن حملنا مع نوح ومن ذرية إبراهيم وإسرائيل وممن هدينا واجتبينا إذا تتلى عليهم آيات الرحمن خروا سجدا وبكيا","އެބޭކަލުންނަކީ، އާދަމުގެފާނުގެ ދަރިކޮޅުން ވަޑައިގަތް ނަބިއްޔުންކުރެ، އެބޭކަލުންގެ މައްޗަށް ﷲ ނިއުމަތް ދެއްވި ބޭކަލުންނެވެ. އަދި ތިމަންރަސްކަލާނގެ، ނޫޙުގެފާނާއެކުގައި (ނަވުގައި) އުފުއްލެވި މީހުންގެ ތެރެއިންވާ ބަޔެކެވެ. އަދި އިބްރާހީމްގެފާނާއި އިސްރާއީލުގެފާނުގެ ދަރިކޮޅުންވާ ބަޔެކެވެ. އަދި ތިމަންރަސްކަލާނގެ ތެދުމަގުދައްކަވައި، ޚިޔާރުކުރެއްވި މީހުންގެ ތެރެއިންވާ ބަޔެކެވެ. އެބޭކަލުންގެ މައްޗަށް ރަޙްމާންވަންތަ ރަސްކަލާނގެ އާޔަތްތައް ކިޔެވޭހިނދު، އެބޭކަލުން ކީރިތިކުރައްވަމުން ސަޖިދަށް ތިރިވެވަޑައިގަންނަވަތެވެ.","",""],["","","","فخلف من بعدهم خلف أضاعوا الصلاة واتبعوا الشهوات فسوف يلقون غيا","ފަހެ، އެބޭކަލުންނަށްފަހު، އެހެންބަޔަކު އައޫއެވެ. އެއުރެން ނަމާދު ދޫކޮށްލޫއެވެ. އަދި ހަވާނަފްސުގެ އެދުންތަކަށް ތަބާ ވޫއެވެ. ފަހެ، ނިކަންހުރެ އެއުރެން ހަލާކާ ކުރިމަތިލާހުށްޓެވެ!","",""],["","","","إلا من تاب وآمن وعمل صالحا فأولئك يدخلون الجنة ولا يظلمون شيئا","ތައުބާވެ، އަދި، އީމާންވެ، އަދި ސާލިހު ޢަމަލުކުޅަ މީހުން މެނުވީއެވެ. ފަހެ، އެއުރެން ސުވަރުގެއަށް ވަންނާނެތެވެ. އަދި އެއުރެންނަށް އެއްވެސް ކަމަކުން ބޭއިންސާފެއް ނުކުރައްވާހުށްޓެވެ.","",""],["","","","جنات عدن التي وعد الرحمن عباده بالغيب إنه كان وعده مأتيا","(އެއީ) ރަޙްމާންވަންތަ ރަސްކަލާނގެ، އެކަލާނގެ އަޅުތަކުންނަށް ޣައިބުގައި ދެއްވުމަށް ވައުދުކުރައްވާފައިވާ، ޢަދަން އޭ ކިއުނު ސުވަރުގެތަކެވެ. ހަމަކަށަވަރުން، އެކަލާނގެ ވައުދު ފުޅަކީ، އަންނާނޭ އެއްޗެއްކަމުގައިވެއެވެ.","",""],["","","","لا يسمعون فيها لغوا إلا سلاما ولهم رزقهم فيها بكرة وعشيا","އެތާނގައި ބޭކާރު ވާހަކައެއް އެއުރެންނަކަށް ނީވޭނެތެވެ. އެހެނެއްކަމަކު، (އިވޭނީ) ސަލާމާއި، ތަޙިއްޔަތުގެ އަޑެވެ. އަދި ހެނދުނާއި، ހަވީރު އެއުރެންގެ ރިޒްގު، އެއުރެންނަށްޓަކައި އެތާނގައި ވެއެވެ.","",""],["","","","تلك الجنة التي نورث من عبادنا من كان تقيا","އެއީ ތިމަންރަސްކަލާނގެ އަޅުންކުރެ، ތަގުވާވެރިވީ މީހުންނަށް ތިމަންރަސްކަލާނގެ ވާރުތަކޮށްދެއްވާ ސުވަރުގެއެވެ.","",""],["","","","وما نتنزل إلا بأمر ربك له ما بين أيدينا وما خلفنا وما بين ذلك وما كان ربك نسيا","އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އަމުރު ފުޅަށް މެނުވީ، ތިމަންމެން ނުފައިބަމެވެ. ތިމަންމެންގެ ކުރިމަތީގައިވާހާ އެއްޗަކާއި، ތިމަންމެންގެ ފަހަތުގައިވާހާ އެއްޗަކާއި، އެދެމެދުގައިވާހާ އެއްޗެއް މިލްކުވެގެންވަނީ، އެކަލާނގެއަށެވެ. އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ހަނދުމަނެތިވެވޮޑިގެންވާ ކަލަކުކަމުގައި ނުވެއެވެ.","",""],["","","","رب السماوات والأرض وما بينهما فاعبده واصطبر لعبادته هل تعلم له سميا","(އެއީ) އުޑުތަކާއި، ބިމާއި، އެދެމެދުގައިވާހާ ތަކެތީގެ ވެރިރަސްކަލާނގެއެވެ. ފަހެ، ކަލޭގެފާނު، އެކަލާނގެއަށް އަޅުކަންކުރައްވާށެވެ! އަދި އެކަލާނގެއަށް އަޅުކަން ކުރެއްވުމުގައި ދެމިހުންނަވައި، ކެތްތެރިވެވަޑައިގަންނަވާށެވެ! އެކަލާނގެއާ އެއްފަދަ އެކައްޗެއްވެސް ވާކަން ކަލޭގެފާނަށް އެނގިވަޑައިގެންވޭތޯއެވެ؟","",""],["","","","ويقول الإنسان أإذا ما مت لسوف أخرج حيا","އިންސާނާ ބުނެތެވެ. ތިމަން މަރުވެދިއުމަށްފަހުގައިވެސް، އަލުން ދިރުމަކަށް ނެރުއްވާނޭހެއްޔެވެ؟","",""],["","","","أولا يذكر الإنسان أنا خلقناه من قبل ولم يك شيئا","އެ އިންސާނާ މީގެކުރިން މައުޖޫދު ވެގެންވާ އެއްޗެއްކަމުގައި ނުވާ ޙާލު، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އޭނާ ހެއްދެވިކަން އޭނާ ހަނދާން ނުކުރަނީހެއްޔެވެ؟","",""],["","","","فوربك لنحشرنهم والشياطين ثم لنحضرنهم حول جهنم جثيا","ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ގަންދެއްވައި ވަހީކުރައްވަމެވެ. ހަމަކަށަވަރުން، ޝައިތާނުންނާ އެކުގައި އެއުރެން މަހުޝަރަށް ފޮނުއްވާހުށީމެވެ. ދެން ކަކޫޖެހިގެންވާ ޙާލު، ނަރަކައިގެ ވަށައިގެން އެއުރެން ގެންނަވާހުށީމެވެ.","",""],["","","","ثم لننزعن من كل شيعة أيهم أشد على الرحمن عتيا","ދެން ތިމަންރަސްކަލާނގެ ކޮންމެ ބަޔެއްގެ ތެރެއިންވެސް އެއުރެންކުރެ ރަޙްމާންވަންތަ ރަސްކަލާނގެއަށް އެންމެ ދެކޮޅުވެރިކަން ބޮޑު މީހުން ވަކިކޮށް ނެރުއްވާހުށީމެވެ.","",""],["","","","ثم لنحن أعلم بالذين هم أولى بها صليا","ދެން ހަމަކަށަވަރުން، އެއުރެންކުރެ ނަރަކަޔަށް ވަނުން އައުލާ ކަންބޮޑީ ކޮންބަޔެއްކަން، އެންމެމޮޅަށް ދެނެވޮޑިގެންވަނީ، ތިމަންރަސްކަލާނގެއެވެ.","",""],["","","","وإن منكم إلا واردها كان على ربك حتما مقضيا","އަދި ތިޔަބައިމީހުންކުރެ ނަރަކަ މަތިންލާފައި ނުދާނޭ ހަމައެކަކުވެސް ނުވެއެވެ. އެއީ ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް ކަނޑައެޅި ލާޒިމުކުރައްވާފައިވާ ކަމެއްކަމުގައިވިއެވެ.","",""],["","","","ثم ننجي الذين اتقوا ونذر الظالمين فيها جثيا","ދެން ތިމަންރަސްކަލާނގެ ތަގުވާވެރިވީ މީހުން ސަލާމަތް ކުރައްވާހުށީމެވެ. އަދި އަނިޔާވެރިވީ މީހުން، ކަކޫޖެހިގެންވާ ޙާލު، އެ ނަރަކައިގެ ތެރެއަށް ދޫކުރައްވާހުށީމެވެ.","",""],["","","","وإذا تتلى عليهم آياتنا بينات قال الذين كفروا للذين آمنوا أي الفريقين خير مقاما وأحسن نديا","އަދި އެއުރެންނަށް ތިމަންރަސްކަލާނގެ އާޔަތްތައް ބަޔާން ވެގެންވާ ގޮތުގައި ކިޔައިދެވޭހިނދު، ކާފިރުވި މީހުން، އީމާންވި މީހުންނަށް ބުނެތެވެ. (ތިމަންމެން) ދެބައިމީހުންކުރެ ދަރަޖައިގެގޮތުން އެންމެމޮޅީ، އަދި މަޖްލިސްގެ ގޮތުން އެންމެރަނގަޅީ، ކޮންބަޔެއްހެއްޔެވެ؟","",""],["","","","وكم أهلكنا قبلهم من قرن هم أحسن أثاثا ورئيا","އަދި ތިމަންރަސްކަލާނގެ އެއުރެންގެ ކުރިން ކިތައް ކިތައް އުއްމަތް ހަލާކުކުރެއްވިން ހެއްޔެވެ؟ މުދާވެރިކަމުގެ ގޮތުންނާއި، ފެންނަ ފެނުމަށް އެއުރެން މާރަނގަޅެވެ.","",""],["","","","قل من كان في الضلالة فليمدد له الرحمن مدا حتى إذا رأوا ما يوعدون إما العذاب وإما الساعة فسيعلمون من هو شر مكانا وأضعف جندا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! މަގުފުރެދުމުގެ ތެރޭގައިވާ މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް ރަޙްމާންވަންތަ ރަސްކަލާނގެ އުމުރު ދިގުކުރައްވައި، މުހުލަތް ދެއްވާނެތެވެ. އެއުރެންނަށް ވައުދުކުރައްވާ ކަންތައް، އެއުރެން ދެކެފުމަށްދާނދެނެވެ. އެހެންޏާ (ދުނިޔޭގެ) އަޒާބެވެ. އެހެންޏާ ގިޔާމަތް ދުވަހުގެ ހަލާކެވެ. ފަހެ، ދަރަޖައިގެ ގޮތުން އެންމެނުބައީ، އަދި ލަޝްކަރުގެގޮތުން އެންމެ ނިކަމެތީ، ކޮންބަޔެއްކަން ނިކަންހުރެ އެއުރެންނަށް އެނގޭނެތެވެ.","",""],["","","","ويزيد الله الذين اهتدوا هدى والباقيات الصالحات خير عند ربك ثوابا وخير مردا","ތެދުމަގު ލިބިގެންފި މީހުންނަށް ﷲ ތެދުމަގު ދެއްކެވުން އިތުރުކުރައްވަތެވެ. އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި، ސަވާބު ލިބުމުގެގޮތުން އެންމެ ހެޔޮވެގެންވަނީ، އަދި ނަތީޖާގެގޮތުން އެންމެ ހެޔޮވެގެންވަނީ، ދެމިހުންނަނިވި ސާލިހު ޢަމަލު ތަކެވެ.","",""],["","","","أفرأيت الذي كفر بآياتنا وقال لأوتين مالا وولدا","ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް ކާފިރުވެ، އަދި ހަމަކަށަވަރުން، ތިމަންނާއަށް މުދަލާއި، ދަރިން ދެއްވާހުށްޓޭ ބުނިމީހާ، ކަލޭގެފާނު ފަހެ، ދެކެވަޑައިގަތީމުތޯއެވެ؟","",""],["","","","أطلع الغيب أم اتخذ عند الرحمن عهدا","އޭނާއަށް ޣައިބު އެނގުނީހެއްޔެވެ؟ ނުވަތަ ރަޙްމާންވަންތަ ރަސްކަލާނގެ ހަޒުރަތުން އަހުދެއް ހިފީހެއްޔެވެ؟","",""],["","","","كلا سنكتب ما يقول ونمد له من العذاب مدا","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. އޭނާ ބުނާއެއްޗެއް ތިމަންރަސްކަލާނގެ ލިޔުއްވާހުށީމެވެ. އަދި އޭނާއަށް އަޒާބު އިތުރުކުރައްވައި ދިގުކުރައްވާހުށީމެވެ.","",""],["","","","ونرثه ما يقول ويأتينا فردا","އަދި އޭނާ އެބުނާ މުދަލާއި، ދަރިން (ނެތިކުރައްވައި) އެހުރިހާ އެއްޗެއް، ތިމަންރަސްކަލާނގެ މިލްކުކުރައްވާހުށީމެވެ. އަދި ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް އޭނާ އަންނަހުށީ، އެކަނިމާ އެކަންޏެވެ.","",""],["","","","واتخذوا من دون الله آلهة ليكونوا لهم عزا","އެއުރެން ﷲ ފިޔަވައި އެހެން އިލާހުންތަކެއް ހިފީ އެއުރެންނަށް ޢިއްޒަތެއްކަމުގައި ވާނޭކަމަށެވެ.","",""],["","","","كلا سيكفرون بعبادتهم ويكونون عليهم ضدا","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. އެ އިލާހު ންތަކަށް އެއުރެން އަޅުކަންކުރުމަށް އިންކާރުކުރާނެތެވެ. އަދި އެ އިލާހު ންތައް އެއުރެންގެ މައްޗަށް އަދާވަތް ތެރިންކަމުގައި ވާނެތެވެ.","",""],["","","","ألم تر أنا أرسلنا الشياطين على الكافرين تؤزهم أزا","ކާފިރުވި މީހުންގެމައްޗަށް ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ޝައިތާނުން ފާކުރެއްވިކަން، ކަލޭގެފާނު ދެނެވަޑައިނުގަންނަވަމުތޯއެވެ؟ އެ ޝައިތާނުން އެއުރެންނަށް ވަސްވާސްދީ ހެއްލުންތެރިކުރެތެވެ.","",""],["","","","فلا تعجل عليهم إنما نعد لهم عدا","ފަހެ، ކަލޭގެފާނު އެއުރެންގެ މައްޗަށް އަވަސްވެވަޑައިނުގަންނަވާށެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެންނަށްޓަކައި (އަޖަލުގެ ދުވަސްތައް) ގުނައި އަދަދުކުރައްވަމެވެ.","",""],["","","","يوم نحشر المتقين إلى الرحمن وفدا","ތަގުވާވެރިން، ރަޙްމާންވަންތަ ރަސްކަލާނގެ ހަޒުރަތަށް (ޢިއްޒަތް ތެރި) ވަފުދެއްގެ ގޮތުގައި ތިމަންރަސްކަލާނގެ އެއްކުރައްވާ ދުވަސް (ހަނދުމަކުރާށެވެ!)","",""],["","","","ونسوق المجرمين إلى جهنم وردا","އަދި ކަރުހިއްކައިގެންފައިވާ ޖަނަވާރުތަކެއް ފެނާދިމާޔަށް ދާފަދައިން، ތިމަންރަސްކަލާނގެ، ކުށްވެރިން ނަރަކަޔާ ދިމާޔަށް ލަވައި ގެންދަވާހުށީމެވެ.","",""],["","","","لا يملكون الشفاعة إلا من اتخذ عند الرحمن عهدا","ރަޙްމާންވަންތަ ރަސްކަލާނގެ ހަޒުރަތުގައި އަހުދެއް ހިފާފައިވާ މީހަކަށް (އެކަލާނގެ އިޒުނަ ދެއްވުމުން) މެނުވީ، އެއުރެންކުރެ އެކަކަށްވެސް ޝަފާއަތް ތެރިވުމުގެ ބާރެއް ލިބިގެނެއްނުވެތެވެ.","",""],["","","","وقالوا اتخذ الرحمن ولدا","ރަޙްމާންވަންތަ ރަސްކަލާނގެ، ދަރިކަލަކު ހިއްޕެވިކަމަށް އެ ކާފިރުވި މީހުން ބުނޫއެވެ.","",""],["","","","لقد جئتم شيئا إدا","ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ތިޔަ ގެނައީ، ވަރަށްވެސް ނުބައިވެގެންވާ ބަހެކެވެ.","",""],["","","","تكاد السماوات يتفطرن منه وتنشق الأرض وتخر الجبال هدا","އެކަމުގެ ސަބަބުން، އުޑުތައް ފަޅަފަޅައިގެންގޮސް، ބިންގަނޑު އިރައިރައިގެންގޮސް، ފަރުބަދަތައް ކުދިކުދިވެ، ވެއްޓިގެން ދިއުން ކައިރިވެގެންވެއެވެ.","",""],["","","","أن دعوا للرحمن ولدا","އެއީ ރަޙްމާންވަންތަ ރަސްކަލާނގެއަށް ދަރިކަލަކުވާކަމަށް އެއުރެން ގޮވުމުގެ ސަބަބުންނެވެ.","",""],["","","","وما ينبغي للرحمن أن يتخذ ولدا","ފަހެ، ދަރިކަލަކު ހިއްޕެވުން ރަޙްމާންވަންތަ ރަސްކަލާނގެއަށް އެކަށީގެނެއް ނުވެއެވެ.","",""],["","","","إن كل من في السماوات والأرض إلا آتي الرحمن عبدا","ރަޙްމާންވަންތަ ރަސްކަލާނގެ ހަޒުރަތަށް އަޅެއްގެ ގޮތުގައި ނާންނާނޭ ހަމައެކަކުވެސް، އުޑުތަކުގައްޔާއި، ބިމުގައި ނުވެތެވެ.","",""],["","","","لقد أحصاهم وعدهم عدا","ހަމަކަށަވަރުން، އެކަލާނގެ އެއުރެން ހިމަނުއްވައި، ފުރިހަމަ އަދަދުކުރެއްވުމަކުން އަދަދުކުރެއްވިއެވެ.","",""],["","","","وكلهم آتيه يوم القيامة فردا","އަދި ގިޔާމަތް ދުވަހުން، އެއުރެންކުރެ ކޮންމެމީހަކު، އެކަލާނގެ ހަޒުރަތަށް އަންނަހުށީ، އެކަނިމާއެކަންޏެވެ.","",""],["","","","إن الذين آمنوا وعملوا الصالحات سيجعل لهم الرحمن ودا","ހަމަކަށަވަރުން، އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަމީހުން (ދަންނާށެވެ!) ރަޙްމާންވަންތަ ރަސްކަލާނގެ، އެއުރެންނަށްޓަކައި ލޯބިލައްވާނެތެވެ.","",""],["","","","فإنما يسرناه بلسانك لتبشر به المتقين وتنذر به قوما لدا","ފަހެ، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނު ވާހަކަދައްކަވާ ބަހުން އެ ގުރްއާން ފަސޭހަކޮށްދެއްވީ، ކަލޭގެފާނު އެ ފޮތުން ތަގުވާވެރިންނަށް އުފާވެރިކަމުގެ ޚަބަރު ދެއްވުމަށާއި، ދެކޮޅުވެރިވެގެންވާ މީހުންނަށް އެއިން އިންޒާރުކުރެއްވުމަށްޓަކައެވެ.","",""],["","","","وكم أهلكنا قبلهم من قرن هل تحس منهم من أحد أو تسمع لهم ركزا","އަދި ތިމަންރަސްކަލާނގެ، އެއުރެންގެ ކުރިން ކިތައްކިތައް އުއްމަތް ހަލާކު ކުރެއްވިންހެއްޔެވެ؟ އެއުރެންކުރެ އެކަކުވެސް، ކަލޭގެފާނަށް ފެނިވަޑައިގަންނަވާތޯއެވެ؟ ނުވަތަ އެއުރެންގެ އެއްވެސް އަޑެއްބަޑެއް، ކަލޭގެފާނަށް އިވިވަޑައިގަންނަވާތޯއެވެ؟","",""],["","","","بسم الله الرحمن الرحيم طه","ط هـ (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","ما أنزلنا عليك القرآن لتشقى","ތިމަންރަސްކަލާނގެ ކަލޭގެފާނުގެ މައްޗަށް މި ގުރްއާން ބާވައިލެއްވީ، ކަލޭގެފާނުގެ ހިތްޕުޅު ދަތިވެ، އަބާއްޖަވެރިވުމަކަށް ނޫނެވެ.","",""],["","","","إلا تذكرة لمن يخشى","(ﷲއަށް) ބިރުވެތިވާ މީހަކަށް ހަނދާންކޮށްދިނުމެއް ކަމުގައި މެނުވީ (ތިމަންރަސްކަލާނގެ އެ ގުރްއާން ބާވައެއް ނުލައްވަމެވެ.)","",""],["","","","تنزيلا ممن خلق الأرض والسماوات العلى","ބިމާއި، އުސްވެގެންވާ އުޑުތައް ހެއްދެވި ރަސްކަލާނގެ ހަޒުރަތުން ބާވައިލެއްވި ވަހީއެކެވެ.","",""],["","","","الرحمن على العرش استوى","ރަޙްމާންވަންތަ ރަސްކަލާނގެ، ޢަރްޝުގެ މައްޗަށް އިސްތިވާވެ ވޮޑިގެންވިއެވެ.","",""],["","","","له ما في السماوات وما في الأرض وما بينهما وما تحت الثرى","އުޑުތަކުގައިވާހާ ތަކެއްޗާއި، ބިމުގައިވާހާ ތަކެއްޗާއި، އެދެމެދުގައިވާހާ ތަކެއްޗާއި، ފަސްގަނޑު ދަށުގައިވާހާ ތަކެއްޗެއް، މިލްކުވެގެންވަނީ އެކަލާނގެއަށެވެ.","",""],["","","","وإن تجهر بالقول فإنه يعلم السر وأخفى","ކަލޭގެފާނު އަޑުހަރުކޮށް ބަސް ވިދާޅުވިޔަސް، ފަހެ، ހަމަކަށަވަރުން، އެކަލާނގެއީ، ސިއްރާއި އެއަށްވުރެ ވަންހަނާ ކަންތައް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","الله لا إله إلا هو له الأسماء الحسنى","ﷲއީ، އެކަލާނގެ ފިޔަވައި ހައްގު ވެގެން އަޅުކަމެއްވެވޭ އިލާހަކު ނުވާ ރަސްކަލާނގެއެވެ. އެންމެ ރިވެތި އިސްމުފުޅުތައް މިލްކުވެގެންވަނީ، އެކަލާނގެއަށެވެ.","",""],["","","","وهل أتاك حديث موسى","މޫސާގެފާނުގެ ވާހަކަ، ކަލޭގެފާނާ ހަމަޔަށް އައިސްފައިވޭތޯއެވެ؟","",""],["","","","إذ رأى نارا فقال لأهله امكثوا إني آنست نارا لعلي آتيكم منها بقبس أو أجد على النار هدى","އެކަލޭގެފާނަށް އަލިފާންގަނޑެއް ފެނިވަޑައިގެންނެވިހިނދެވެ. ފަހެ، އެކަލޭގެފާނުގެ އަހުލުވެރިންނަށް ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން މިތާނގައި ތިބޭށެވެ! ހަމަކަށަވަރުން، އަހުރެންނަށް އަލިފާންގަނޑެއް ފެނިއްޖެއެވެ. (އަހުރެން މިދަނީ) އެތަނުން ތިޔަބައިމީހުންނަށް ހުޅުކޮޅެއް ގެނެސްދެވޭތޯއެވެ. ނުވަތަ އެ އަލިފާންގަނޑުގެ ކައިރިން، އަހުރެންނަށް ކޮންމެވެސް މަގެއް ފެނޭތޯއެވެ.","",""],["","","","فلما أتاها نودي يا موسى","ފަހެ، އެކަލޭގެފާނު އެ އަލިފާންގަނޑުގެ ކައިރިޔަށް ވަޑައިގަތްހިނދު، ނިދާ އިއްވެވިއެވެ. އޭ މޫސާގެފާނެވެ!","",""],["","","","إني أنا ربك فاخلع نعليك إنك بالواد المقدس طوى","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެއީ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއެވެ. ފަހެ، ކަލޭގެފާނުގެ ފައިވާންޖޯޑުކޮޅު ބާލުއްވާށެވެ! ހަމަކަށަވަރުން، ކަލޭގެފާނު ތިޔަހުންނެވީ، ޠުވާ އޭ ކިއުނު މުގައްދަސް ވާދީ ގައެވެ.","",""],["","","","وأنا اخترتك فاستمع لما يوحى","އަދި ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނު ޚިޔާރުކުރައްވައިފީމެވެ. ފަހެ، (ކަލޭގެފާނަށް) އިއްވަވާ ވަހީއަށް ކަނުލައި އައްސަވާށެވެ!","",""],["","","","إنني أنا الله لا إله إلا أنا فاعبدني وأقم الصلاة لذكري","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެއީ ﷲއެވެ. ތިމަންރަސްކަލާނގެ މެނުވީ، އިލާހަކު ނުވެއެވެ. ފަހެ، ތިމަންރަސްކަލާނގެއަށް ކަލޭގެފާނު އަޅުކަން ކުރައްވާށެވެ! އަދި ތިމަންރަސްކަލާނގެ ހަނދުމަކުރެއްވުމަށްޓަކައި، ނަމާދު ގާއިމުކުރައްވާށެވެ!","",""],["","","","إن الساعة آتية أكاد أخفيها لتجزى كل نفس بما تسعى","ހަމަކަށަވަރުން، ގިޔާމަތް ވުމުގެ ވަގުތަކީ، އަންނާނޭ އެއްޗެކެވެ. ތިމަންރަސްކަލާނގެ އެވަގުތު ވަންހަނާ ކުރެއްވުމަށް އިރާދަކުރައްވާފައިވަނީ، ކޮންމެ ނަފްސަކަށްވެސް، އެ ނަފްސެއް ކުޅަ ޢަމަލުގެ ޖަޒާ ލިބުމަށްޓަކައެވެ.","",""],["","","","فلا يصدنك عنها من لا يؤمن بها واتبع هواه فتردى","ފަހެ، އެދުވަހަށް އީމާން ނުވެ، އޭނާގެ ހަވާނަފްސަށް ތަބާ ވެއްޖެމީހާ، ހަމަކަށަވަރުން، އެކަމުން (އެބަހީ: ގިޔާމަތް ދުވަސް ހަނދުމަކުރެއްވުމުން) ކަލޭގެފާނު ދުރުކުރިޔަ ނުދޭހުށިކަމެވެ! އޭރުން ކަލޭގެފާނު ހަލާކުވެދާ ހުށްޓެވެ.","",""],["","","","وما تلك بيمينك يا موسى","އޭ މޫސާގެފާނެވެ! ކަލޭގެފާނުގެ ކަނާތްޕުޅުގައި އެވަނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","قال هي عصاي أتوكأ عليها وأهش بها على غنمي ولي فيها مآرب أخرى","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އެއީ އަޅުގެ އަސާއެވެ. އޭގެމައްޗަށް މިއަޅާ ބުރަވެ، މިއަޅާގެ ބަކަރިތަކަށް (ކާންދިނުމަށް) އެއިން (ގަސްގަހުގެ) ފަތް ބިންނަމެވެ. އަދި އެހެން ބޭނުންތައްވެސް މިއަޅާއަށް އޭގައިވެއެވެ.","",""],["","","","قال ألقها يا موسى","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. އޭ މޫސާގެފާނެވެ! އެ އަސާ އެއްލަވާށެވެ!","",""],["","","","فألقاها فإذا هي حية تسعى","ފަހެ، އެކަލޭގެފާނު އެ އަސާ އެއްލެވިއެވެ. ދެން އެހާރުން، ދުވެދުވެއޮތް ހަރުފައަކަށް ވެއްޖެއެވެ.","",""],["","","","قال خذها ولا تخف سنعيدها سيرتها الأولى","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ކަލޭގެފާނު އެ އަސާގައި ހިއްޕަވާށެވެ! އަދި ބިރުފުޅުނުގަންނާށެވެ! އެ އަސާ، ކުރިން އޮތްގޮތަށް ތިމަންރަސްކަލާނގެ އިއާދަކުރައްވާހުށީމެވެ.","",""],["","","","واضمم يدك إلى جناحك تخرج بيضاء من غير سوء آية أخرى","އަދި ކަލޭގެފާނުގެ ކިހިލިފަތްޕުޅުދަށަށް ކަލޭގެފާނުގެ އަތްތިލަފުޅު ލައްވާށެވެ! އެއްވެސް ބަލިމަޑުކަމެއްނެތި، ހުދުކޮށް (ވިދަވިދައި އޮންނަގޮތުގައި) އެ އަތްތިލަފުޅު ނުކުންނާނެއެވެ. (އެއީ) އެހެން މުއުޖުޒާތެއްގެ ގޮތުގައެވެ.","",""],["","","","لنريك من آياتنا الكبرى","ތިމަންރަސްކަލާނގެ ބޮޑެތި މުއުޖުޒާތްތަކުގެ ތެރެއިން ބައެއް، ކަލޭގެފާނަށް ދެއްކެވުމަށްޓަކައެވެ.","",""],["","","","اذهب إلى فرعون إنه طغى","ފިރްޢައުނުގެ ގާތަށް ކަލޭގެފާނު ވަޑައިގަންނަވާށެވެ! ހަމަކަށަވަރުން، ފުރެދުމުގައި އޭނާ ހައްދުފަހަނަޅައި ހިނގައްޖެއެވެ.","",""],["","","","قال رب اشرح لي صدري","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! މިއަޅާއަށްޓަކައި މިއަޅާގެ ހިތް ތަނަވަސްކޮށްދެއްވާނދޭވެ!","",""],["","","","ويسر لي أمري","އަދި މިއަޅާގެ ކަންތައް މިއަޅާއަށް ފަސޭހަކޮށްދެއްވާނދޭވެ!","",""],["","","","واحلل عقدة من لساني","އަދި މިއަޅާގެ ދުލުގެ ގޮށް މޮއްސަވައިލައްވާނދޭވެ! (އެބަހީ: ދުލުގައިހުރި ދަތިގޮތް ފިލުއްވައިދެއްވައި، ދޫފަސޭހަކޮށްދެއްވާނދޭވެ!)","",""],["","","","يفقهوا قولي","އެއީ ތިމަންކަލޭގެފާނުގެ ބަސް އެއުރެންނަށް ވިސްނި، އެނގުމަށްޓަކައެވެ.","",""],["","","","واجعل لي وزيرا من أهلي","އަދި ތިމަންކަލޭގެފާނުގެ އަހުލުވެރިންގެ ތެރެއިން ވާގިވެރިޔަކު ތިމަންކަލޭގެފާނަށް ލައްވާނދޭވެ!","",""],["","","","هارون أخي","(އެއީ) ތިމަންކަލޭގެފާނުގެ އަޚު ހާރޫނުގެފާނެވެ.","",""],["","","","اشدد به أزري","އެކަލޭގެފާނުގެ ސަބަބުން ތިމަންކަލޭގެފާނުގެ ބާރުގަދަ ކުރައްވާނދޭވެ!","",""],["","","","وأشركه في أمري","އަދި ތިމަންކަލޭގެފާނުގެ ކަންތަކުގައި (އެބަހީ: ރަސޫލުކަމާއި، އެކަން ތަލްބީޣުކުރެއްވުމުގެ މަސްއޫލިއްޔަތުގައި) އެކަލޭގެފާނު ބައިވެރިކުރައްވާނދޭވެ!","",""],["","","","كي نسبحك كثيرا","އަޅަމެން އިބަރަސްކަލާނގެއަށް ގިނަގިނައިން ތަސްބީހަ ދެންނެވުމަށްޓަކައެވެ.","",""],["","","","ونذكرك كثيرا","އަދި ގިނަގިނައިން އަޅަމެން އިބަރަސްކަލާނގެ ހަނދުމަކުޅައުމަށްޓަކައެވެ.","",""],["","","","إنك كنت بنا بصيرا","ހަމަކަށަވަރުން، އަޅަމެންނާމެދު މޮޅަށް ބައްލަވާވޮޑިގެންވާ ކަލަކު ކަމުގައި އިބަރަސްކަލާނގެ ވޮޑިގެންވަމުއެވެ.","",""],["","","","قال قد أوتيت سؤلك يا موسى","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. އޭ މޫސާގެފާނެވެ! ހަމަކަށަވަރުން، ކަލޭގެފާނު އެދިވަޑައިގަންނަވާ ކަންތައް ކަލޭގެފާނަށް ދެއްވައިފިއެވެ.","",""],["","","","ولقد مننا عليك مرة أخرى","އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނުގެ މައްޗަށް އެހެންފަހަރަކު ދަރުވަމަންތަވެ ވޮޑިގެންވީމެވެ.","",""],["","","","إذ أوحينا إلى أمك ما يوحى","އިލްހާމްކުރައްވާ އެއްޗެއް ތިމަންރަސްކަލާނގެ ކަލޭގެފާނުގެ މަންމާއަށް އިލްހާމްކުރެއްވިހިނދެވެ.","",""],["","","","أن اقذفيه في التابوت فاقذفيه في اليم فليلقه اليم بالساحل يأخذه عدو لي وعدو له وألقيت عليك محبة مني ولتصنع على عيني","ފޮށީގެ ތެރެޔަށް އެ ދަރިކަލުން ލައްވާށެވެ! އަދި (ނީލަ) ކޯރުގެ ތެރެޔަށް އެ ފޮށި އެއްލައިލައްވާށެވެ! ދެން ކޯރު، އެ ފޮށި، ގޮނޑުދޮށަށް ލައްގުވާނެތެވެ. (އޭރުން) ތިމަންރަސްކަލާނގެ އަދުއްވު، އަދި އެ ދަރިކަލުންގެވެސް އަދުއްވު އެ ފޮށި ނަގާނެތެވެ. އަދި ކަލޭގެފާނުގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ހަޒުރަތުން ލޯބިލެއްވީމެވެ. އެއީ ތިމަންރަސްކަލާނގެ ބެއްލެވުމުގެ ދަށުން ކަލޭގެފާނު ބޮޑުފުޅުވުމަށެވެ.","",""],["","","","إذ تمشي أختك فتقول هل أدلكم على من يكفله فرجعناك إلى أمك كي تقر عينها ولا تحزن وقتلت نفسا فنجيناك من الغم وفتناك فتونا فلبثت سنين في أهل مدين ثم جئت على قدر يا موسى","ކަލޭގެފާނުގެ އުޚްތު ވަޑައިގެން ވިދާޅުވި ހިނދެވެ. (ކިރުފޮދު އަރުވައި) އެ ދަރިކަލުން ބެލެހެއްޓުމަށް ޙަވާލު ވާނެ މީހަކު، ތިޔަބައިމީހުންނަށް ތިމަންދައްކަން ހެއްޔެވެ؟ ފަހެ، (މިގޮތުން) ތިމަންރަސްކަލާނގެ ކަލޭގެފާނުގެ މައިކަމަނާގެ އަރިހަށް ކަލޭގެފާނު އަނބުރާ ގެންދެވީމެވެ. އެއީ އެކަމަނާގެ ލޯފުޅަށް ފިނިކަން ޙާޞިލު ވުމަށްޓަކައެވެ. އަދި އެކަމަނާ ހިތާމަނުކުރެއްވުމަށްޓަކައެވެ. އަދި ކަލޭގެފާނު މީހަކު ގަތުލުކުރެއްވުމުން ލިބިވަޑައިގެންނެވި ހިތާމަފުޅުން ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު މިންޖުކުރެއްވީމެވެ. އަދި ކަލޭގެފާނު ފުރިހަމަޔަށް އިމްތިހާނުކުރެއްވީމެވެ. އޭ މޫސާގެފާނެވެ! މަދްޔަންގެ އަހުލުވެރިންގެ ތެރޭގައި އަހަރުތަކެއް ވަންދެން ކަލޭގެފާނު ހުންނެވީމުއެވެ. ދެން މިންވަރު ކުރައްވާފައިވާ ގޮތުގެމަތިން (މިތަނަށް) ކަލޭގެފާނު ތިޔަވަޑައިގަތީއެވެ.","",""],["","","","واصطنعتك لنفسي","އަދި ތިމަންރަސްކަލާނގެއަށްޓަކައި (އެބަހީ: ވަހީއާއި ރިސާލަތު ތަބްލީޣުކުރެއްވުމަށްޓަކައި) ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ޚިޔާރުކުރެއްވީމެވެ.","",""],["","","","اذهب أنت وأخوك بآياتي ولا تنيا في ذكري","ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާއިގެން ކަލޭގެފާނާއި، ކަލޭގެފާނުގެ އަޚު ވަޑައިގަންނަވާށެވެ! އަދި ތިމަންރަސްކަލާނގެ ހަނދުމަކުރެއްވުމުގައި، ތިޔަ ދެބޭކަލުން ފަރުވާކުޑަ ނުކުރައްވާށެވެ!","",""],["","","","اذهبا إلى فرعون إنه طغى","ފިރްޢައުނުގެ ގާތަށް ތިޔަ ދެބޭކަލުން ވަޑައިގަންނަވާށެވެ! ހަމަކަށަވަރުން، އޭނާ އަނިޔާވެރިވެ ހައްދުފަހަނަޅައި ހިނގައްޖެއެވެ.","",""],["","","","فقولا له قولا لينا لعله يتذكر أو يخشى","ފަހެ، މަޑުމައިތިރި ބަހުން ތިޔަދެބޭކަލުން އޭނާއަށް ބަސް ވިދާޅުވާށެވެ! (އެއީ) އޭނާ ހަނދުމަކޮށް، ނުވަތަ ބިރުވެތިވޭތޯ އެކަމުގެ އުންމީދުގައެވެ.","",""],["","","","قالا ربنا إننا نخاف أن يفرط علينا أو أن يطغى","އެ ދެބޭކަލުން ދެންނެވިއެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! އޭނާ އަޅަމެންގެ މައްޗަށް (އުގޫބާތް ދިނުމަށް) އަވަސްވެގަނެ، ނުވަތަ އަނިޔާވެރިވެ، ހައްދުފަހަނަޅައި ހިނގައިދާނެކަމަށް، ހަމަކަށަވަރުން، އަޅަމެން ބިރުގަނެތެވެ.","",""],["","","","قال لا تخافا إنني معكما أسمع وأرى","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ތިޔަ ދެބޭކަލުން ބިރުފުޅު ނުގަންނާށެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އައްސަވާވޮޑިގެން، އަދި ބައްލަވާވޮޑިގެންވާ ޙާލު، ތިޔަ ދެބޭކަލުންނާ އެކުގައި ވޮޑިގެންވަމެވެ.","",""],["","","","فأتياه فقولا إنا رسولا ربك فأرسل معنا بني إسرائيل ولا تعذبهم قد جئناك بآية من ربك والسلام على من اتبع الهدى","ފަހެ، ތިޔަ ދެބޭކަލުން އޭނާގެ ގާތަށް ވަޑައިގެން ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ތިމަންމެންނީ ކަލޭގެ ވެރިރަސްކަލާނގެ ފޮނުއްވި ދެ ރަސޫލުންނެވެ. ފަހެ، ތިމަންމެންނާ އެކުގައި އިސްރާއީލުގެދަރިން ފޮނުވާށެވެ! އަދި އެއުރެންނަށް ކަލޭ އަޒާބު ނުދޭށެވެ! ހަމަކަށަވަރުން، ކަލޭގެގާތަށް ތިމަންމެން މިއައީ، ކަލޭގެ ވެރިރަސްކަލާނގެ ހަޒުރަތު ންވާ، މުއުޖިޒާއަކާއިގެންނެވެ. ތެދުމަގަށް ތަބާ ވެއްޖެ މީހަކަށް ސަލާމަތްކަން ހުށްޓެވެ.","",""],["","","","إنا قد أوحي إلينا أن العذاب على من كذب وتولى","ހަމަކަށަވަރުން (ﷲގެ ރިސާލަތް) ދޮގުކޮށް، އެނބުރި ފުރަގަސްދިން މީހެއްގެ މައްޗަށް، ހަމަކަށަވަރުން، އަޒާބު ހުރިކަމަށް ތިމަންމެންނަށް ވަހީކުރައްވާފައިވެއެވެ.","",""],["","","","قال فمن ربكما يا موسى","އޭނާ ބުންޏެވެ. އޭ މޫސާގެފާނެވެ! ތިޔަ ދެބޭކަލުންގެ ވެރިރަސްކަލާނގެއަކީ ފަހެ، ކާކުހެއްޔެވެ؟","",""],["","","","قال ربنا الذي أعطى كل شيء خلقه ثم هدى","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިމަންމެންގެ ވެރިރަސްކަލާނގެއީ، ކޮންމެ އެއްޗަކަށްމެ، އެ އެއްޗެއްގެ ސިފައާއި، ޠަބީޢަތް ދެއްވައި، ދެން ތެދުމަގު ދެއްކެވި ރަސްކަލާނގެއެވެ.","",""],["","","","قال فما بال القرون الأولى","އޭނާ ބުންޏެވެ. އިހުގެ ޖީލުތަކުގެ ކަންތައް ހުރިގޮތަކީ، ފަހެ، ކޮބައިހެއްޔެވެ؟","",""],["","","","قال علمها عند ربي في كتاب لا يضل ربي ولا ينسى","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އެކަމުގެ އިލްމު ވަނީ، ތިމަންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ލިޔުއްވާފައެވެ. ތިމަންގެ ވެރިރަސްކަލާނގެއަށް އޮޅިވޮޑިއެއް ނުގަންނަވަތެވެ. އަދި އެކަލާނގެ ހަނދުމަނެތިވެވޮޑިއެއްވެސް ނުގަންނަވަތެވެ.","",""],["","","","الذي جعل لكم الأرض مهدا وسلك لكم فيها سبلا وأنزل من السماء ماء فأخرجنا به أزواجا من نبات شتى","އެކަލާނގެއީ، ތިޔަބައިމީހުންނަށް ތަންމައްޗެއްކަމުގައި، ބިންލެއްވި ރަސްކަލާނގެއެވެ. އަދި އެތާނގައި، ތިޔަބައިމީހުންނަށް މަގުތައް ދެއްކެވި ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެ އުޑުން ފެންވެއްސެވިއެވެ. ދެން އެ ފެނުގެ ސަބަބުން، ތިމަންރަސްކަލާނގެ ފަތްޕިލާވެލީގެ ތަފާތު ބާވަތްތައް ނެރުއްވީމެވެ.","",""],["","","","كلوا وارعوا أنعامكم إن في ذلك لآيات لأولي النهى","ތިޔަބައިމީހުން ކާށެވެ! އަދި ތިޔަބައިމީހުންގެ ނަޢަމް ސޫފިތަކަށް ކާންދީ ހުއިހައްޕާށެވެ! ހަމަކަށަވަރުން، އެކަމުގައި ބުއްދީގެ އަހުލުވެރިންނަށް ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","منها خلقناكم وفيها نعيدكم ومنها نخرجكم تارة أخرى","ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން ހެއްދެވީ އެ ބިމުންނެވެ. އަދި ތިޔަބައިމީހުން އަނބުރާ އިއާދަކުރައްވާހުށީވެސް އެ ބިމަށެވެ. އަދި ދެވަނަފަހަރަށް ތިޔަބައިމީހުން ނެރުއްވާހުށީވެސް އެ ބިމުންނެވެ.","",""],["","","","ولقد أريناه آياتنا كلها فكذب وأبى","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އޭނާޔަށް ތިމަންރަސްކަލާނގެ ހުރިހާ އާޔަތް ތަކެއް ދެއްކެވީމެވެ. ފަހެ، އޭނާ އެ އާޔަތްތައް ދޮގުކޮށް (އީމާން ނުވެ) އެކަމުން މަނާވެގަތެވެ.","",""],["","","","قال أجئتنا لتخرجنا من أرضنا بسحرك يا موسى","އޭނާ ބުންޏެވެ. އޭ މޫސާގެފާނެވެ! ކަލޭގެފާނު ތިމަންމެންގާތަށް ތިޔަވަޑައިގަތީ، ކަލޭގެފާނުގެ ޖާދޫގެ ބާރުން ތިމަންމެންގެ ބިމުން ތިމަންމެން ނެރުއްވުމަށްޓަކައިތޯއެވެ؟","",""],["","","","فلنأتينك بسحر مثله فاجعل بيننا وبينك موعدا لا نخلفه نحن ولا أنت مكانا سوى","ފަހެ، ހަމަކަށަވަރުން، އެފަދަ ޖާދޫއެއް ކަލޭގެފާނަށް ތިމަންމެންވެސް ގެންނަހުށީމެވެ. ފަހެ، ތިމަންމެންވެސް އަދި ކަލޭގެފާނުވެސް އެއްބަސްވެ ހަމަހަމަވެގެންވާ ތަނެއްގެގޮތުން އެ މައުޢިދަކާ ޚިލާފު ނުވާނެ މައުޢިދެއް ތިމަންމެންނާއި، ކަލޭގެފާނާ ދެމެދު ކަނޑައަޅުއްވާށެވެ!","",""],["","","","قال موعدكم يوم الزينة وأن يحشر الناس ضحى","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންގެ މައުޢިދަކީ ޒީނަތްތެރިކަމުގެ (ޢީދު) ދުވަހެވެ. އަދި އިރުއަރައި އަލިވެގެން އަންނަވަގުތު، މީހުން އެއްކުރެވެން ވާނެއެވެ.","",""],["","","","فتولى فرعون فجمع كيده ثم أتى","ދެން ފިރްޢައުނު އެނބުރި ހިނގައްޖެއެވެ. އަދި އޭނާގެ ޙީލަތް ތެރި ރޭވުންތައް ރާވައި، އޭނާގެ ޖާދޫގަރުން އެއްކުރުމަށްފަހު، ދެން (އެތަނަށް) އަތުވެއްޖެއެވެ.","",""],["","","","قال لهم موسى ويلكم لا تفتروا على الله كذبا فيسحتكم بعذاب وقد خاب من افترى","މޫސާގެފާނު އެއުރެންނަށް ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންނަށް ގެއްލުމާއި ހަލާކު ހުށްޓެވެ. ﷲއާމެދު ތިޔަބައިމީހުން ހަދައިގެން ދޮގުނުބުނާށެވެ! ފަހެ، ﷲގެ އަޒާބުގެ ސަބަބުން، ތިޔަބައިމީހުން ހަލާކުވެ ނެތިވެހިނގައިދާނެތެވެ. އަދި ހަމަކަށަވަރުން (ﷲއާމެދު) ދޮގުހަދައިފިމީހާ ގެއްލެނިވެ، ނިކަމެތިވެގެން ހިނގައިދާހުށްޓެވެ.","",""],["","","","فتنازعوا أمرهم بينهم وأسروا النجوى","ދެން އެއުރެންގެ ކަންތަކާމެދު (އެބަހީ: މޫސާގެފާނާމެދު) އެއުރެންގެ މެދުގައި ޚިލާފުވެ ދެކޮޅުވެރިވެއްޖައޫއެވެ. އަދި އެއުރެންކުޅަ ސައްލާތައް (މީސްތަކުންނަށް) އެއުރެން ސިއްރުކޮށްފޫއެވެ.","",""],["","","","قالوا إن هذان لساحران يريدان أن يخرجاكم من أرضكم بسحرهما ويذهبا بطريقتكم المثلى","އެއުރެން ބުނެފޫއެވެ. ހަމަކަށަވަރުން، މިއީ ދެ ޖާދޫގަރުންކަން ކަށަވަރެވެ. އެ ދެމީހުން އެދެނީ، އެ ދެމީހުންގެ ޖާދޫގެބާރުން ތިޔަބައިމީހުންގެ ބިމުން ތިޔަބައިމީހުން ނެރެލުމަށެވެ. އަދި ތިޔަބައިމީހުންގެ ދެވަނައެއްނެތް މޮޅު ދީނާއި ގޮތް، ނެތިކޮށްލުމަށެވެ.","",""],["","","","فأجمعوا كيدكم ثم ائتوا صفا وقد أفلح اليوم من استعلى","ފަހެ، ތިޔަބައިމީހުންގެ ރޭވުންތައް މޮޅަށް ރާވާށެވެ! ދެން ތިޔަބައިމީހުން (ޖާދޫގަރުންނާއި ޢާއްމުންގެ މީހުން) ސަފަކަށްތިބެ އަންނާށެވެ! ހަމަކަށަވަރުން، މިއަދު މޮޅުވެ، މަތިވެރިވި މީހަކަށް ކާމިޔާބު ލިބިއްޖެކަން ކަށަވަރެވެ.","",""],["","","","قالوا يا موسى إما أن تلقي وإما أن نكون أول من ألقى","އެއުރެން ބުނެފޫއެވެ. އޭ މޫސާގެފާނެވެ! އެހެންވިއްޔާ ފުރަތަމަ (އަސާ) އެއްލަވާނީ ކަލޭގެފާނުތޯއެވެ؟ އެހެންނޫނިއްޔާ ފުރަތަމަ އެއްލާމީހުން ކަމުގައިވާނީ ތިމަންމެންތޯއެވެ؟","",""],["","","","قال بل ألقوا فإذا حبالهم وعصيهم يخيل إليه من سحرهم أنها تسعى","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަދި ކީއްހެއްޔެވެ؟ ތިޔަބައިމީހުން (ފުރަތަމަ) އެއްލާށެވެ! ފަހެ (އެއުރެން އެއްލިހިނދު) އެހާރުން އެއުރެންގެ ވާބުރިތަކާއި، އަސާތައް އެއުރެންގެ ޖާދޫގެ ސަބަބުން ދުވާހެން އެކަލޭގެފާނަށް ހީފުޅުވިއެވެ.","",""],["","","","فأوجس في نفسه خيفة موسى","ފަހެ، މޫސާގެފާނުގެ ހިތްޕުޅުގައި ބިރުވެރިކަމެއް ހިނގިއެވެ.","",""],["","","","قلنا لا تخف إنك أنت الأعلى","ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވީމެވެ. ކަލޭގެފާނު ބިރުފުޅު ނުގަންނާށެވެ! ހަމަކަށަވަރުން، ކާމިޔާބުލިބި މޮޅުވާނީ ހަމަކަލޭގެފާނެވެ.","",""],["","","","وألق ما في يمينك تلقف ما صنعوا إنما صنعوا كيد ساحر ولا يفلح الساحر حيث أتى","އަދި ކަލޭގެފާނުގެ ކަނާތްޕުޅުގައިވާ އެތި (އެބަހީ: އަސާ) އެއްލަވާށެވެ! އޭރުން، އެ އަސާ އެއުރެން ހެދި ތަކެތި ކައި، ދިރުވާލައިފާނެތެވެ. ހަމަކަށަވަރުން، އެއުރެން ހެދި އެއްޗެހި ވާކަން ކަށަވަރީ (ހަމައެކަނި) ޖާދޫގަރުންގެ މަކަރު ކަމުގައެވެ. އަދި ޖާދޫގަރު ކޮންމެ އެއްޗެއް ގެނައިކަމުގައިވިޔަސް، އޭނާއަކަށް ކާމިޔާބެއް ނުވާނެތެވެ.","",""],["","","","فألقي السحرة سجدا قالوا آمنا برب هارون وموسى","ފަހެ، ޖާދޫގަރުން ސަޖިދަށް ތިރިވޫއެވެ. އެއުރެން ބުނޫއެވެ. ހާރޫނުގެފާނާއި، މޫސާގެފާނުގެ ވެރިރަސްކަލާނގެއަށް ތިމަންމެން އީމާން ވެއްޖައީމުއެވެ.","",""],["","","","قال آمنتم له قبل أن آذن لكم إنه لكبيركم الذي علمكم السحر فلأقطعن أيديكم وأرجلكم من خلاف ولأصلبنكم في جذوع النخل ولتعلمن أينا أشد عذابا وأبقى","އޭނާ (އެބަހީ: ފިރްޢައުނު) ބުންޏެވެ. ތިޔަބައިމީހުންނަށް ތިމަން އިޒުނަ ދިނުމުގެ ކުރިން، އޭނާޔަށް (އެބަހީ: މޫސާގެފާނަށް) ތިޔަބައިމީހުން އީމާން ވީ ހެއްޔެވެ؟ ހަމަކަށަވަރުން، އޭނާޔަކީ ކަލޭމެންނަށް ޖާދޫ ދަސްކޮށްދިން ކަލޭމެންގެ ބޮޑުމީހާކަން ކަށަވަރެވެ. ފަހެ، ހަމަކަށަވަރުން، ކަލޭމެންގެ އަތްތަކާއި، ކަލޭމެންގެ ފައިތައް ތަފާތުކޮށް އަހުރެން ކަނޑާހުށީމެވެ. އަދި ކަދުރުރުކު ގަސްގަނޑުގައި ހަމަކަށަވަރުން، ކަލޭމެން ޞަލީބަށް އަރުވާހުށީމެވެ. އަދި ހަމަކަށަވަރުން، އަހުރެމެންކުރެ ގަދަފަދަ، އަދި ދެމިހުރުންބޮޑު އަޒާބެއްދެވޭނީ ކާކަށްކަން ކަލޭމެންނަށް ނިކަންހުރެ އެނގޭހުށްޓެވެ.","",""],["","","","قالوا لن نؤثرك على ما جاءنا من البينات والذي فطرنا فاقض ما أنت قاض إنما تقضي هذه الحياة الدنيا","އެއުރެން ބުނޫއެވެ. ބަޔާން ވެގެންވާ ހުއްޖަތާއި، ދަލީލުގެ ތެރެއިން ތިމަންމެންނާ ހަމަޔަށް އައިސްފައިވާ އެއްޗަކާއި، ތިމަންމެން ހެއްދެވި ކަލާނގެއަށްވުރެ މައްޗަކަށް ތިމަންމެން ކަލޭ އިހެއްނުކުރާހުށީމެވެ. ފަހެ، ކަލޭގެ ކަނޑައަޅާގޮތަކަށް ކަނޑައަޅައި ނިންމާށެވެ! ހަމަކަށަވަރުން، ކަލެޔަށް ކަނޑައަޅައި ނިންމޭނީ (ހަމައެކަނި) މި ދުނިޔޭގެ ހަޔާތް ގައެވެ.","",""],["","","","إنا آمنا بربنا ليغفر لنا خطايانا وما أكرهتنا عليه من السحر والله خير وأبقى","ހަމަކަށަވަރުން، ތިމަންމެންގެ ވެރިރަސްކަލާނގެއަށް ތިމަންމެން އީމާން ވެއްޖައީމުއެވެ. އެއީ އެކަލާނގެ ތިމަންމެންގެ ކުށްތަކާއި، ކަލޭ ތިމަންމެންނަށް މަޖުބޫރުކުޅަ ޖާދޫއާމެދު، ތިމަންމެންނަށް (އަފޫކުރައްވައި) ފާފަފުއްސެވުމަށްޓަކައެވެ. އަދި ﷲއީ، އެންމެ ހެޔޮވެގެންވާ، އަދި އެންމެ ދެމިވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","إنه من يأت ربه مجرما فإن له جهنم لا يموت فيها ولا يحيى","ހަމަކަށަވަރުން، އެމީހެއްގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ކުށްވެރިއެއްގެ ގޮތުގައި އަންނަމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އެމީހަކަށްހުރީ ނަރަކަޔެވެ. އެތާނގައި އޭނާ މަރެއް ނުވާނެތެވެ. އަދި (ފުރިހަމަ ދިރުމަކުން) ނުމެދިރޭނޭމެއެވެ.","",""],["","","","ومن يأته مؤمنا قد عمل الصالحات فأولئك لهم الدرجات العلى","އަދި ހަމަކަށަވަރުން، މުއުމިނެއްގެ ގޮތުގައި، ސާލިހު ޢަމަލުތައްކޮށް، އެކަލާނގެ ހަޒުރަތަށް އަތުވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންނަށް (އާޚިރަތުގައި) ހުރީ މަތިވެރިވެގެންވާ ދަރަޖައެވެ.","",""],["","","","جنات عدن تجري من تحتها الأنهار خالدين فيها وذلك جزاء من تزكى","އެތާނގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާހުރި ޢަދަން އޭ ކިއުނު ސުވަރުގެތަކެވެ. އެތާނގައި، އެއުރެން ދެމިތިބެނިވި ގޮތުގައެވެ. އެއީ (ނުބައިކަންތަކުން) ތާހިރު ވެގަތް މީހާގެ ޖަޒާއެވެ.","",""],["","","","ولقد أوحينا إلى موسى أن أسر بعبادي فاضرب لهم طريقا في البحر يبسا لا تخاف دركا ولا تخشى","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް ވަހީކުރެއްވީމެވެ. ތިމަންރަސްކަލާނގެ އަޅުންނާއިގެން ރޭގަނޑުގައި ހިންގަވައި (މިސްރުގެ ބިމުން) ނުކުމެވަޑައިގަންނަވާށެވެ! އަދި އެއުރެންނަށް ކަނޑުގައި ހިކިފައިވާ މަގެއް ހައްދަވާށެވެ! (ފިރްޢައުނުގެ ލަޝްކަރު) އަތުލައިގެންފާނެތީ، ބިރުފުޅުނުގެން ހުންނަވާ ޙާލު ގައެވެ. އަދި (ކަނޑުގައި ޣަރަގު ވެދާނެތީވެސް) ބިރުފުޅުނުގެން ހުންނަވާ ޙާލު ގައެވެ.","",""],["","","","فأتبعهم فرعون بجنوده فغشيهم من اليم ما غشيهم","ފަހެ، ފިރްޢައުނު އޭނާގެ ލަޝްކަރާއިގެން އެއުރެންގެ ފަހަތުން ދިޔައެވެ. ދެން ކަނޑުގެ ލޮނުގަނޑު އެ ލަޝްކަރު އެކަށް ފޮރުވާލައި ނިވާކޮށްލައިފިއެވެ.","",""],["","","","وأضل فرعون قومه وما هدى","ފިރްޢައުނު އޭނާގެ ގައުމުގެމީހުން މަގުފުރެއްދިއެވެ. އަދި އޭނާ (އެއުރެންނަކަށް) ތެދުމަގެއްވެސް ނުދެއްކިއެވެ.","",""],["","","","يا بني إسرائيل قد أنجيناكم من عدوكم وواعدناكم جانب الطور الأيمن ونزلنا عليكم المن والسلوى","އޭ އިސްރާއީލުގެދަރިންނޭވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންގެ އަދުއްވުންގެ ކިބައިން ތިޔަބައިމީހުން ސަލާމަތްކޮށްދެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް (އެބަހީ: މޫސާގެފާނަށް) ޠޫރު ފަރުބަދައިގެ ކަނާތްފަރާތަށް (ވަޑައިގަތުމަށް) މީޢާދެއް ކަނޑައެޅުއްވީމެވެ. އަދި ތިޔަބައިމީހުންގެ މައްޗަށް މައްނާއި ސަލްވާ ބާވައިލެއްވީމެވެ. (ނޯޓު: މައްނަކީ ބަޔެއް މުފައްސިރުން ވިދާޅުވާގޮތުގައި ފިނިފައިބާގޮތަށް ފައިބާއެއްޗެކެވެ. އެއީ މާމުއިކަހަލަ ފޮނި އެއްޗެކެވެ. އަނެއްބައި މުފައްސިރުން ވިދާޅުވާގޮތުގައި އެއީ ގަނޑުފެނާ އެއްފަދަ މާމުޔަށްވުރެ ފޮނި، ކިރަށްވުރެ ހުދު އެއްޗެކެވެ. ސަލްވާއަކީ ބާވަތެއްގެ ދޫންޏެކެވެ.)","",""],["","","","كلوا من طيبات ما رزقناكم ولا تطغوا فيه فيحل عليكم غضبي ومن يحلل عليه غضبي فقد هوى","ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް ދެއްވި ހަލާލު ތަކެތިން ތިޔަބައިމީހުން ކައިއުޅޭށެވެ! އެކަމުގައި ތިޔަބައިމީހުން ހައްދުފަހަނަޅައި ނުދާށެވެ! ފަހެ، އޭރުން ތިޔަބައިމީހުންގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ކޯފާ އަތުވެދާހުށްޓެވެ. އަދި އެމީހެއްގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ކޯފާ އަތުވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކު ވެއްޓި ހަލާކުވެ ހިނގައްޖެއެވެ.","",""],["","","","وإني لغفار لمن تاب وآمن وعمل صالحا ثم اهتدى","ތައުބާވެ އީމާންވެ ސާލިހު ޢަމަލު ކޮށް، ދެން ތެދުމަގު ލިބިގެންފި މީހާއަށް ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","وما أعجلك عن قومك يا موسى","އޭ މޫސާގެފާނެވެ! ކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށްވުރެން އަވަސްވެވަޑައިގެން ވަޑައިގަންނަވަންޖެހުނީ ކީއްވެގެންތޯއެވެ؟","",""],["","","","قال هم أولاء على أثري وعجلت إليك رب لترضى","އެކަލޭގެފާނު ދެންނެވިއެވެ. އެއުރެން މިއަޅާގެ ފަހަތުން އެބައާދެތެވެ. އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! އިބަރަސްކަލާނގެ ހަޒުރަތަށް އައުމަށް ތިމަންއަޅާ އަވަސްވެގަތީ، އިބަރަސްކަލާނގެ (މިއަޅާއަށް) ރުއްސެވުން އިތުރުވުމަށްޓަކައެވެ.","",""],["","","","قال فإنا قد فتنا قومك من بعدك وأضلهم السامري","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ފަހެ، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ފަހުގައި، ކަލޭގެފާނުގެ ގައުމުގެމީހުން އިމްތިހާނުކުރެއްވީމެވެ. އަދި އައްސާމިރީ (އޭ ކިއުނު މީހަކު) އެއުރެން މަގުފުރެއްދިއެވެ.","",""],["","","","فرجع موسى إلى قومه غضبان أسفا قال يا قوم ألم يعدكم ربكم وعدا حسنا أفطال عليكم العهد أم أردتم أن يحل عليكم غضب من ربكم فأخلفتم موعدي","ފަހެ، މޫސާގެފާނު ކޯފާވެ، ހިތާމަކުރައްވާ ޙާލު، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ގާތަށް އެނބުރި ވަޑައިގަތެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް ރަނގަޅު ވައުދަކުން ވައުދެއް ނުކުރައްވާހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުންގެ މައްޗަށް ޒަމާން ދިގުވެގެން ދިޔައީހެއްޔެވެ؟ ނުވަތަ ތިޔަބައިމީހުންގެ މައްޗަށް ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ކޯފާއެއް އައުމަށް ތިޔަބައިމީހުން އެދެނީހެއްޔެވެ؟ އެހެނީ ތިޔަބައިމީހުން، ތިމަންކަލޭގެފާނަށް ކުރި ވައުދާ ޚިލާފު ވެއްޖައީމުއެވެ.","",""],["","","","قالوا ما أخلفنا موعدك بملكنا ولكنا حملنا أوزارا من زينة القوم فقذفناها فكذلك ألقى السامري","އެއުރެން ދެންނެވޫއެވެ. ތިމަންމެން އަމިއްލަ އިޚްތިޔާރަކުން ކަލޭގެފާނަށް ކުޅަ ވައުދަކާ ޚިލާފެއް ނުވަމުއެވެ. އެހެނެއްކަމަކު، ގައުމުގެމީހުންގެ ގަހަނާތަކުން ބުރަތަކެއް ތިމަންމެންނަށް އުފުލާން ޖެހުނީއެވެ. ފަހެ، ތިމަންމެން އެ ގަހަނާތައް (އަލިފާންގަނޑަށް) އުކީމުއެވެ. ހަމައެފަދައިން އައްސާމިރީ ވެސް އުކިއެވެ.","",""],["","","","فأخرج لهم عجلا جسدا له خوار فقالوا هذا إلهكم وإله موسى فنسي","ފަހެ، އޭނާ އެއުރެންނަށް ޅަ ގެރިއެއްގެ ސިފައިގައިވާ، އަދި އޭގެ އަޑުކަހަލަ އަޑެއްވާ ހަށިގަނޑެއް ނެރެދިނެވެ. ފަހެ، އެއުރެން ބުނޫއެވެ. މިއީ ތިޔަބައިމީހުންގެ އިލާހެވެ. އަދި މޫސާގެފާނުގެވެސް އިލާހެވެ. (އެކަން އެންގެވުމަށް) މޫސާގެފާނު ހަނދުމަފުޅު ނެތުނީއެވެ.","",""],["","","","أفلا يرون ألا يرجع إليهم قولا ولا يملك لهم ضرا ولا نفعا","ފަހެ، އެ ބުދު އެއުރެންނަށް ޖަވާބެއް ނުދޭކަމާއި، އެއުރެންނަށް ގެއްލުމެއް، އަދި މަންފާއެއް ދިނުންވެސް އެއަށް މިލްކުވެގެން ނުވާކަން އެއުރެންނަށް ނޭނގެނީހެއްޔެވެ؟","",""],["","","","ولقد قال لهم هارون من قبل يا قوم إنما فتنتم به وإن ربكم الرحمن فاتبعوني وأطيعوا أمري","ހަމަކަށަވަރުން، މީގެކުރިން ހާރޫނުގެފާނު އެއުރެންނަށް ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! އެ ގެރި މެދުވެރިކޮށް ތިޔަބައިމީހުން އިމްތިހާނުކުރެއްވީކަން ކަށަވަރެވެ. އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއީ، ރަޙްމާންވަންތަ ރަސްކަލާނގެއެވެ. ފަހެ، ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނަށް ތަބާ ވާށެވެ! އަދި ތިމަންކަލޭގެފާނުގެ އަމުރަށް ކިޔަމަންވާށެވެ!","",""],["","","","قالوا لن نبرح عليه عاكفين حتى يرجع إلينا موسى","އެއުރެން ދެންނެވޫއެވެ. މޫސާގެފާނު ތިމަންމެންގެ ގާތަށް އެނބުރި ވަޑައިގެންފުމަށް ދާނދެން، ތިމަންމެން އެޔަށް އަޅުކަންކުރުންމަތީ ދެމިތިބޭނޫއެވެ.","",""],["","","","قال يا هارون ما منعك إذ رأيتهم ضلوا","އެކަލޭގެފާނު (އެބަހީ: މޫސާގެފާނު) ވިދާޅުވިއެވެ. އޭ ހާރޫނުގެފާނެވެ! އެއުރެން މަގުފުރެދިގެން ދިޔަތަން ކަލޭގެފާނަށް ފެނިވަޑައިގަތްހިނދު، ތިމަންކަލޭގެފާނަށް ތަބާވެ، ތިމަންކަލޭގެފާނުގެ އަރިހަށް ވަޑައިގަތުން ކަލޭގެފާނަށް މަނާކުރީ ކޮންކަމެއްތޯއެވެ؟ ފަހެ، ތިމަންކަލޭގެފާނުގެ އަމުރަށް ކަލޭގެފާނު އުރެދިވަޑައިގަތީތޯއެވެ؟","",""],["","","","ألا تتبعن أفعصيت أمري","އެކަލޭގެފާނު (އެބަހީ: މޫސާގެފާނު) ވިދާޅުވިއެވެ. އޭ ހާރޫނުގެފާނެވެ! އެއުރެން މަގުފުރެދިގެން ދިޔަތަން ކަލޭގެފާނަށް ފެނިވަޑައިގަތްހިނދު، ތިމަންކަލޭގެފާނަށް ތަބާވެ، ތިމަންކަލޭގެފާނުގެ އަރިހަށް ވަޑައިގަތުން ކަލޭގެފާނަށް މަނާކުރީ ކޮންކަމެއްތޯއެވެ؟ ފަހެ، ތިމަންކަލޭގެފާނުގެ އަމުރަށް ކަލޭގެފާނު އުރެދިވަޑައިގަތީތޯއެވެ؟","",""],["","","","قال يا ابن أم لا تأخذ بلحيتي ولا برأسي إني خشيت أن تقول فرقت بين بني إسرائيل ولم ترقب قولي","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ މަންމާގެ ދަރިކަލުންނޭވެ! ތިމަންގެ ތުނބުޅީގައްޔާއި، ބޮލުގެ އިސްތަށިގަނޑުގައި ނުހިއްޕަވާށެވެ! ހަމަކަށަވަރުން، އިސްރާއީލުގެދަރިން ބައިބައިކުރިކަމަށް ކަލޭގެފާނު ވިދާޅުވާނެތީ، ތިމަން ބިރުގަތީއެވެ. އަދި ތިމަންގެ ބަހަކަށް ކަލޭގެފާނު އިންތިޒާރެއް ނުކުރައްވަމުއެވެ.","",""],["","","","قال فما خطبك يا سامري","އެކަލޭގެފާނު (އެބަހީ: މޫސާގެފާނު) ވިދާޅުވިއެވެ. އޭ ސާމިރީއެވެ! ފަހެ، ކަލޭ އެގޮތަށް ކަންތައްކުރަންޖެހުނީ ކީއްވެގެންހެއްޔެވެ؟","",""],["","","","قال بصرت بما لم يبصروا به فقبضت قبضة من أثر الرسول فنبذتها وكذلك سولت لي نفسي","އެކަލޭގެ ދެންނެވިއެވެ. އެއުރެން ނުދެކޭ އެއްޗެއް ތިމަންނާ ދުށީމެވެ. ފަހެ، ފޮނުއްވާފައިވާ މަލާއިކަތާގެ (އެބަހީ: ޖިބްރީލުގެފާނުގެ އަސްކޮޅުގެ) ފިޔަވަޅު ޖެހުނުތަނުން ފަސްމުށެއް ނެގީމެވެ. އަދި އެ ފަސްމުށް (އެ ގެރީގެ މައްޗަށް) އެއްލީމެވެ. ތިމަންގެ ނަފްސު ތިމަންނައަށް ޒީނަތްތެރިކޮށްދިނީ އެފަދައިންނެވެ.","",""],["","","","قال فاذهب فإن لك في الحياة أن تقول لا مساس وإن لك موعدا لن تخلفه وانظر إلى إلهك الذي ظلت عليه عاكفا لنحرقنه ثم لننسفنه في اليم نسفا","އެކަލޭގެފާނު ވިދާޅުވިއެވެ! ފަހެ، ދާންއުޅޭށެވެ! ފަހެ، ހަމަކަށަވަރުން، (ދުނިޔޭގެ) ހަޔާތުގައި ކަލެޔަށްއޮތީ (އެއްވެސް މީހެއްގައި) ބީހުމެއްނެތޭ ބުނުމެވެ. އަދި ހަމަކަށަވަރުން (އާޚިރަތުގައި) ޚިލާފު ނުވެވޭނެ މައުޢިދެއް ކަލެޔަށް ވެއެވެ. އަދި ކަލޭ، އެއަށް އަޅުކަންކުރުންމަތީ ދެމިހުރި، ކަލޭގެ އިލާހަށް ބަލާށެވެ! ހަމަށަވަރުން، ތިމަންކަލޭގެފާނު އޭތި އަންދައިލައްވާހުށީމެވެ. އަދި ހަމަކަށަވަރުން، ކަނޑުތެރެޔަށް އޭގެ އަޅިތައް ބުރުއްސައިލައްވާހުށީމެވެ.","",""],["","","","إنما إلهكم الله الذي لا إله إلا هو وسع كل شيء علما","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ އިލާހަކީ ﷲއެވެ. އެކަލާނގެއީ، އެކަލާނގެ ފިޔަވައި އެހެން އިލާހަކު ނުވާ ރަސްކަލާނގެއެވެ. އެކަލާނގެ އިލްމުފުޅު ހުރިހާ އެއްޗެއްގެ މައްޗަށް ތަނަވަސްވެގެންވެއެވެ.","",""],["","","","كذلك نقص عليك من أنباء ما قد سبق وقد آتيناك من لدنا ذكرا","އިސްވެދިޔަ އުއްމަތްތަކުގެ ޚަބަރު ތަކުން ކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ ކިޔައިދެއްވަނީ، އެފަދައިންނެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ހަޒުރަތުން ކަލޭގެފާނަށް ގުރްއާން ދެއްވީމެވެ.","",""],["","","","من أعرض عنه فإنه يحمل يوم القيامة وزرا","އެ ގުރްއާނަށް ފުރަގަސްދީފިމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އެމީހަކު ގިޔާމަތް ދުވަހުން ބުރަދަންހުރި ފާފައެއް އުފުލާހުށްޓެވެ.","",""],["","","","خالدين فيه وساء لهم يوم القيامة حملا","އޭގެ އަޒާބުގައި އެއުރެން ދެމިތިބޭ ޙާލު ގައެވެ. އަދި ގިޔާމަތް ދުވަހުން އެއުރެން އުފުލާ ބުރައިގެ ހުރި ނުބައިކަމާއެވެ!","",""],["","","","يوم ينفخ في الصور ونحشر المجرمين يومئذ زرقا","ތާޅަފިލި ފުމެލައްވާ ދުވަހުއެވެ. އަދި އެދުވަހުން ކުށްވެރިން (ގެ މޫނުތައް ބިރުވެރިކަމުން) ނޫވެގެންވާ ޙާލު، މަހުޝަރަށް ފޮނުއްވާހުށީމެވެ.","",""],["","","","يتخافتون بينهم إن لبثتم إلا عشرا","އެއުރެންގެ މެދުގައި އެއްބަޔަކު އަނެއްބަޔަކަށް ސިއްރު ވާހަކަ ދައްކަމުން ބުނާނެތެވެ. ތިޔަބައިމީހުން (ދުނިޔެމަތީގައި) ދިހަ ދުވަހު މެނުވީ ނުތިބެމުއެވެ.","",""],["","","","نحن أعلم بما يقولون إذ يقول أمثلهم طريقة إن لبثتم إلا يوما","އެއުރެން (އެބަހީ: ކާފިރުން) ބުނެއުޅޭ ބަސްތައް ތިމަންރަސްކަލާނގެ މޮޅަށް ދެނެވޮޑިގެންވަމެވެ. އެއުރެންކުރެ އެންމެ ރަނގަޅުގޮތަށް ވިސްނިމީހާ ބުނިހިނދެވެ. ތިޔަބައިމީހުން އެންމެ ދުވަހަކު މެނުވީ ނުތިބެމުއެވެ.","",""],["","","","ويسألونك عن الجبال فقل ينسفها ربي نسفا","އަދި އެއުރެން ފަރުބަދަތަކާމެދުގައި ކަލޭގެފާނާ ސުވާލުކުރެތެވެ. ފަހެ، ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެތަކެތި ފުނޑުފުޑުކޮށްލައްވައި ބުރުއްސަވައިލައްވާނެތެވެ.","",""],["","","","فيذرها قاعا صفصفا","ފަހެ، ގަހެއް ރުކެއްނެތް ހަމަބިމެއްގެ ގޮތުގައި އެކަލާނގެ އެ ބިން ދޫކުރައްވާނެތެވެ.","",""],["","","","لا ترى فيها عوجا ولا أمتا","އެ ބިމުން ގުދުކަމެއް ނުވަތަ އަޑިގުޑަންކަމެއް ތިބާޔަކަށް ނުފެންނާނެތެވެ.","",""],["","","","يومئذ يتبعون الداعي لا عوج له وخشعت الأصوات للرحمن فلا تسمع إلا همسا","އެދުވަހުން ގޮވައިލާމީހާއަށް އެއުރެން ތަބާ ވާނެތެވެ. އެކަމަށް އެއްވެސް ގުދުކަމެއްނެތެވެ. އަދި ރަޙްމާންވަންތަ ރަސްކަލާނގެއަށް (ބިރުވެތިވެ) އަޑުތައް ހިމޭންވާނެއެވެ. ފަހެ (ފިޔަވަޅުގެ އަޑުކަހަލަ) މަޑު އަޑެއް މެނުވީ ތިބާޔަކަށް ނީވޭނެތެވެ.","",""],["","","","يومئذ لا تنفع الشفاعة إلا من أذن له الرحمن ورضي له قولا","ރަޙްމާންވަންތަ ރަސްކަލާނގެ އެމީހަކަށް އިޒުނަ ދެއްވައި، އަދި އެމީހަކުގެ ބަހަށް ރުހިވޮޑިގެންފިމީހަކަށް މެނުވީ، އެދުވަހުން ޝަފާއަތް ތެރިވުމުގެ މަންފާއެއް ނުކުރާނެތެވެ.","",""],["","","","يعلم ما بين أيديهم وما خلفهم ولا يحيطون به علما","އެއުރެންގެ ކުރިމަތީގައިވާ ކަންތަކާއި، އެއުރެންގެ ފަހަތުގައިވާ ކަންތައްތައް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަދި އެއުރެންނަކަށް އެކަންތައްތަކެއް އެނގިގެނެއް ނުވެތެވެ.","",""],["","","","وعنت الوجوه للحي القيوم وقد خاب من حمل ظلما","ދިރިދެމިވޮޑިގެންވާ، ދާއިމަށް ގާއިމު ވެވޮޑިގެންވާ ރަސްކަލާނގެއަށްޓަކައި، މޫނުތައް ދެރަވެ ނިކަމެތިވެއްޖެއެވެ. އަދި (ޝިރުކުގެ) އަނިޔާވެރިކަން އުފުލައިގެން އަންނަމީހާ، ނާކާމިޔާބުވެއްޖެކަން ކަށަވަރެވެ.","",""],["","","","ومن يعمل من الصالحات وهو مؤمن فلا يخاف ظلما ولا هضما","އަދި މުއުމިނަކު ކަމުގައިވާ ޙާލު، ސާލިހު ޢަމަލުތައް ކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، އަނިޔާއެއް ލިބިދާނެކަމަކަށް އަދި ހައްގެއް އުނިވެދާނެކަމަކަށްވެސް އޭނާ ބިރެއް ނުގަންނާނެތެވެ.","",""],["","","","وكذلك أنزلناه قرآنا عربيا وصرفنا فيه من الوعيد لعلهم يتقون أو يحدث لهم ذكرا","އަދި ހަމައެފަދައިން، އަރަބި ބަހުންވާ ގުރްއާނެއްކަމުގައި ތިމަންރަސްކަލާނގެ އެ ފޮތް ބާވައިލެއްވީމެވެ. އަދި އެ ފޮތުގައި ތިމަންރަސްކަލާނގެ ވަޢީދުތައް ތަފްޞީލު ކޮށް ބަޔާންކުރެއްވީމެވެ. (އެއީ) އެއުރެން ބިރުވެތިވެ، ތަގުވާވެރިވުމަށްޓަކައެވެ. ނުވަތަ އެއުރެންނަށް ހަނދާންކޮށްދީ، އިބްރަތް ލިބިދިނުމަށެވެ.","",""],["","","","فتعالى الله الملك الحق ولا تعجل بالقرآن من قبل أن يقضى إليك وحيه وقل رب زدني علما","ފަހެ، ރަސްވަންތަ، ހައްގުވަންތަ ﷲ މަތިވެރިވެ ވޮޑިގެންވެއެވެ. ކަލޭގެފާނަށް ވަހީ ބާވައިލައްވައި ނިމުމުގެކުރިން ކަލޭގެފާނު އެ ގުރްއާން ކިޔަވައިވިދާޅުވުމަށް އަވަސްވެވަޑައި ނުގަންނަވާށެވެ! އަދި ކަލޭގެފާނު ވިދާޅުވާށެވެ! އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! މިއަޅާއަށް އިލްމު އިތުރުކޮށްދެއްވާނދޭވެ!","",""],["","","","ولقد عهدنا إلى آدم من قبل فنسي ولم نجد له عزما","ހަމަކަށަވަރުން، މީގެކުރިން ތިމަންރަސްކަލާނގެ އާދަމުގެފާނަށް ވަސިއްޔަތްކުރައްވައި، އަހުދު ހިއްޕެވީމެވެ. ފަހެ، އެކަލޭގެފާނު (އެ އަހުދު) ހަނދުމަނެތުނެވެ. އަދި އެކަލޭގެފާނުގެ ކިބައިން އެއްވެސް ޢަޒުމަކާއި، ޘާބިތުކަމެއް ތިމަންރަސްކަލާނގެ ދެކެވޮޑިއެއް ނުގަންނަވަމެވެ.","",""],["","","","وإذ قلنا للملائكة اسجدوا لآدم فسجدوا إلا إبليس أبى","އާދަމުގެފާނަށް ތިޔަބައިމީހުން ސަޖިދަކުރާށޭ ތިމަންރަސްކަލާނގެ މަލާއިކަތުންނަށް ވަހީކުރެއްވިހިނދު، ހަނދުމަކުރާށެވެ! ފަހެ، އިބްލީސް ފިޔަވައި އެ މަލާއިކަތުން ސަޖިދަކުރެއްވޫއެވެ. އެކަލޭގެ އެކަމުން މަނާވެގަތެވެ.","",""],["","","","فقلنا يا آدم إن هذا عدو لك ولزوجك فلا يخرجنكما من الجنة فتشقى","ފަހެ، ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވީމެވެ. އޭ އާދަމުގެފާނެވެ! ހަމަކަށަވަރުން، މިއީ ކަލޭގެފާނާއި، ކަލޭގެފާނުގެ އަނބިކަނބަލުންނަށްހުރި އަދާވަތް ތެރިޔެކެވެ. ފަހެ، އެކަލޭގެ ތިޔަ ދެކަނބަލުން ސުވަރުގެއިން ނެރެލިޔަނުދެއްވާހުށިކަމެވެ! އޭރުން ކަލޭގެފާނު ދަތިތަކާ ކުރިމަތިލައްވަން ޖެހިވަޑައިގެންފާނެތެވެ.","",""],["","","","إن لك ألا تجوع فيها ولا تعرى","ހަމަކަށަވަރުން، ކަލޭގެފާނަކަށް އެތާނގައި ބަނޑުހައިވުމެއްނުވެތެވެ. އަދި އުނުއޮރިޔާންވުމެއްވެސް ނުމެވޭމެއެވެ.","",""],["","","","وأنك لا تظمأ فيها ولا تضحى","އަދި ހަމަކަށަވަރުން، ކަލޭގެފާނަށް އެތާނގައި ކަރުހިއްކުމެއް ނުލިބޭނެތެވެ. އަދި ކަލޭގެފާނަށް އަވީގެ ހޫނެއްވެސް ނުމެވާނެމެއެވެ.","",""],["","","","فوسوس إليه الشيطان قال يا آدم هل أدلك على شجرة الخلد وملك لا يبلى","ފަހެ، ޝައިތާނާ އެކަލޭގެފާނަށް ވަސްވާސްދީ ބުންޏެވެ. އޭ އާދަމުގެފާނެވެ! (އެ ގަހުން ފަރިއްކުޅުއްވައިފިނަމަ، ކަލޭގެފާނު އަބަދަށް ދެމިހުންނަވާނެ) ޝަޖަރަތުލް ޚުލްދި ގަހާއި، ފަނާވެގެންނުދާނޭ ވެރިކަމެއް، ކަލޭގެފާނަށް ތިމަން ދައްކަންތޯއެވެ؟","",""],["","","","فأكلا منها فبدت لهما سوآتهما وطفقا يخصفان عليهما من ورق الجنة وعصى آدم ربه فغوى","ފަހެ، އެ ދެކަނބަލުން އެ ގަހުން ފަރިއްކުޅުއްވިއެވެ. ދެން އެ ދެކަނބަލުންގެ ޢައުރަ، އެ ދެކަނބަލުންނަށް ފާޅުވިއެވެ. އަދި ސުވަރުގޭގެ ފަތްތަކުން ޢައުރަ ނިވާކުރައްވަން ފެއްޓެވިއެވެ. އަދި އާދަމުގެފާނު އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް އުރެދިވަޑައިގަތެވެ. ފަހެ، އެކަލޭގެފާނުގެ މަގްޞަދު ޙާޞިލު ނުވެ މަގުގެއްލުނެވެ.","",""],["","","","ثم اجتباه ربه فتاب عليه وهدى","ދެން އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، އެކަލޭގެފާނު ޚިޔާރުކުރެއްވިއެވެ. ފަހެ، އެކަލޭގެފާނުގެ މައްޗަށް ތައުބާ ލައްވައި ތެދުމަގު ދެއްކެވިއެވެ.","",""],["","","","قال اهبطا منها جميعا بعضكم لبعض عدو فإما يأتينكم مني هدى فمن اتبع هداي فلا يضل ولا يشقى","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ތިޔަދެކަނބަލުން އެކުގައި ސުވަރުގެއިން (ބިމަށް) ފައިބައިވަޑައިގަންނަވާށެވެ! ތިޔަބައިމީހުންގެ އެއްބަޔަކު އަނެއްބަޔަކަށް އަދާވަތް ތެރިން ކަމުގައިވާ ޙާލު ގައެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ ހަޒުރަތުން ތިޔަބައިމީހުންނަށް ތެދުމަގެއް އަތުވެއްޖެނަމަ، ދެން ތިމަންރަސްކަލާނގެ ތެދުމަގަށް ތަބާ ވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކު މަގުފުރެދިގެނެއް ނުދާނެތެވެ. އަދި އަބާއްޖަވެރިއެއްވެސް ނުމެވާނޭމެއެވެ.","",""],["","","","ومن أعرض عن ذكري فإن له معيشة ضنكا ونحشره يوم القيامة أعمى","އަދި ތިމަންރަސްކަލާނގެ ގުރްއާނަށް ފުރަގަސްދީފިމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އެމީހަކަށްއޮތީ، ދަތި ދިރިއުޅުމެކެވެ. އަދި ގިޔާމަތް ދުވަހުން އެމީހަކު ކަނުމީހެއްގެ ގޮތުގައި މަހުޝަރަށް ފޮނުއްވާހުށީމެވެ.","",""],["","","","قال رب لم حشرتني أعمى وقد كنت بصيرا","އެމީހާ ދަންނަވާނެތެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ކަނުމީހެއްގެ ގޮތުގައި މިއަޅާ މަހުޝަރަށް ފޮނުއްވީ ކީއްވެތޯއެވެ؟ ހަމަކަށަވަރުން، ލޮލަށްފެންނަ މީހަކު ކަމުގައި (ދުނިޔެމަތީގައި) މިއަޅާވީމެވެ.","",""],["","","","قال كذلك أتتك آياتنا فنسيتها وكذلك اليوم تنسى","އެކަލާނގެ ވަހީކުރައްވާނެތެވެ. ހަމައެފަދައިން ތިމަންރަސްކަލާނގެ އާޔަތްތައް ކަލެޔާ ހަމަޔަށްއައެވެ. ފަހެ، އެ އާޔަތްތައް ކަލޭ ހަނދާން ނައްތައިލީމުއެވެ. ހަމައެފަދައިން، މިއަދު ކަލޭގެމަތިން ހަނދާން ނައްތައިލެވޭނެތެވެ. (އެބަހީ: ﷲގެ ރަހުމަތުން މަޙްރޫމު ކޮށްލެވޭނެތެވެ.)","",""],["","","","وكذلك نجزي من أسرف ولم يؤمن بآيات ربه ولعذاب الآخرة أشد وأبقى","އަދި (އުރެދުމުގައި) ހައްދުފަހަނަޅައިގޮސް، އަދި އޭނާގެ ވެރިރަސްކަލާނގެ އާޔަތްތަކަށް އީމާން ނުވިމީހާއަށް، ތިމަންރަސްކަލާނގެ ޖަޒާދެއްވަނީ އެފަދައިންނެވެ. އަދި ހަމަކަށަވަރުން، އާޚިރަތްގެ އަޒާބު މާގަދައެވެ. އަދި ދެމިހުރުން މާބޮޑުމެއެވެ.","",""],["","","","أفلم يهد لهم كم أهلكنا قبلهم من القرون يمشون في مساكنهم إن في ذلك لآيات لأولي النهى","ފަހެ، އެއުރެންގެ ކުރިން ތިމަންރަސްކަލާނގެ ކިތައްކިތައް އުއްމަތް ހަލާކުކުރެއްވިކަން އެއުރެންނަށް ބަޔާން ވެގެން ނުވޭހެއްޔެވެ؟ އެއުރެންގެ ގޮވަތިގެދޮރުހުރި ތަންތާނގައި، އެއުރެން ހިނގައިއުޅޭ ޙާލު ގައެވެ. ހަމަކަށަވަރުން، އެކަމުގައި ބުއްދީގެ އަހުލުވެރިންނަށް ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","ولولا كلمة سبقت من ربك لكان لزاما وأجل مسمى","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން (އެއުރެންނަށް އަޒާބު ލަސްކުރެއްވުމުގެ) ކަލިމަ ފުޅެއް އިސްވެގޮސްފައި ނުވާނަމަ، އަދި ކަނޑައެޅިގެންވާ މުއްދަތެއް ނުވާނަމަ (އެއުރެންނަށް ދުނިޔެމަތީގައި) އަޒާބު ދެއްވުން ލާޒިމް ވެއްޖައީހެވެ.","",""],["","","","فاصبر على ما يقولون وسبح بحمد ربك قبل طلوع الشمس وقبل غروبها ومن آناء الليل فسبح وأطراف النهار لعلك ترضى","ފަހެ، އެއުރެން ބުނާބަސްތަކަށް ކަލޭގެފާނު ކެތްކުރައްވާށެވެ! އަދި އިރުއެރުމުގެ ކުރީގައްޔާއި އަދި އިރުއޮއްސުމުގެ ކުރީގައި، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް ހަމްދާއެކު ތަސްބީހަ ވިދާޅުވާށެވެ! (އެބަހީ: ނަމާދު ކުރައްވާށެވެ!) އަދި ރޭގަނޑުގެ ވަގުތުތަކުން ބައެއްގައްޔާއި، ދުވާލުގެ ދެކޮޅުގައި ކަލޭގެފާނު ތަސްބީހަ ވިދާޅުވާށެވެ! (އެބަހީ: ނަމާދު ކުރައްވާށެވެ!) އެއީ ކަލޭގެފާނު ރުހިވަޑައިގަތުމަށްޓަކައެވެ. (ނޯޓު: މި އާޔަތުގައި ފަރުޟު ފަސްނަމާދުގެ ވަގުތުތައް ބަޔާން ވެގެންވާ ކަމުގައި މުފައްސިރުން ލިޔުއްވާފައިވެއެވެ.)","",""],["","","","ولا تمدن عينيك إلى ما متعنا به أزواجا منهم زهرة الحياة الدنيا لنفتنهم فيه ورزق ربك خير وأبقى","އަދި އެއުރެންގެ ތެރެއިން ބަޔަކަށް ދުނިޔަވީ ހަޔާތްގެ ޒީނަތްތެރިކަމުގެ ގޮތުން ތިމަންރަސްކަލާނގެ އެތަކެއްޗާމެދު އެއުރެން އިމްތިހާނުކުރެއްވުމަށްޓަކައި، ދެއްވި ތަކެއްޗަށް އެދިވަޑައިގެން، ކަލޭގެފާނު ނުބައްލަވާށެވެ! ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ދެއްވަވާ ތަކެތި ހެޔޮކަން ބޮޑެވެ. އަދި ދެމިހުރުން މާބޮޑުމެއެވެ.","",""],["","","","وأمر أهلك بالصلاة واصطبر عليها لا نسألك رزقا نحن نرزقك والعاقبة للتقوى","އަދި ކަލޭގެފާނުގެ އަހުލުވެރިންނަށް ނަމާދުކުރުމަށް އަމުރުކުރައްވާށެވެ! އަދި އެކަމުގެ މައްޗަށް ކެތްތެރިވެވަޑައިގަންނަވާށެވެ! ރިޒްގު ދެއްވުމަކަށް ކަލޭގެފާނުގެ ކިބަޔަކުން ތިމަންރަސްކަލާނގެ އެދިވޮޑިއެއް ނުގަންނަވަމެވެ. ކަލޭގެފާނަށް ރިޒްގު ދެއްވަނީ، ތިމަންރަސްކަލާނގެއެވެ. ރަނގަޅު ނިމުންވަނީ، ތަގުވާވެރިންނަށެވެ.","",""],["","","","وقالوا لولا يأتينا بآية من ربه أولم تأتهم بينة ما في الصحف الأولى","އެއުރެން ބުނޫއެވެ. އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އެކަލޭގެފާނު ތިމަންމެންނަށް މުއުޖިޒާއެއް ނުގެންނަވަނީ ކީއްވެގެން ހެއްޔެވެ؟ ފަހެ، (އެއުރެން އެހެންބުނާއިރު) ކުރީގެ ފޮތްތަކުގައި ބަޔާން ވެގެންވާ ހެކިތައް އެއުރެންނާ ހަމަޔަކަށް ނާދޭހެއްޔެވެ؟","",""],["","","","ولو أنا أهلكناهم بعذاب من قبله لقالوا ربنا لولا أرسلت إلينا رسولا فنتبع آياتك من قبل أن نذل ونخزى","އޭގެކުރިން (އެބަހީ: ގުރްއާން ބާވައިލެއްވުމުގެ، ނުވަތަ މުޙައްމަދުގެފާނު ފޮނުއްވުމުގެ ކުރިން) ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އަޒާބުން އެއުރެން ހަލާކުކުރެއްވިނަމަ، އެއުރެން ބުނީސްކަން ކަށަވަރެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! އިބަރަސްކަލާނގެ އަޅަމެންގެ ގާތަށް ރަސޫލަކު ނުފޮނުއްވެވީ ކީއްވެގެންތޯއެވެ؟ ފަހެ، އޭރުން ތިމަންމެން ދެރަވެ ހަލާކުވުމުގެ ކުރީގައި އިބަރަސްކަލާނގެ އާޔަތްތަކަށް ތަބާ ވީމުހެވެ.","",""],["","","","قل كل متربص فتربصوا فستعلمون من أصحاب الصراط السوي ومن اهتدى","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ކޮންމެމީހަކީވެސް (އެމީހަކަށް އަތުވެދާނެ ކަންކަމާމެދު) އިންތިޒާރުކުރާ މީހެކެވެ. ފަހެ، ތިޔަބައިމީހުންވެސް އިންތިޒާރުކުރާށެވެ! ފަހެ، ސީދާވެގެންވާ ތެދުމަގުގެ އަހުލުވެރިންނަކީ އަދި ހިދާޔަތް ލިބިގެންވާ މީހުންނަކީ، ކޮބައިކަން، ނިކަންހުރެ ތިޔަބައިމީހުންނަށް އެނގޭނެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم اقترب للناس حسابهم وهم في غفلة معرضون","މީސްތަކުންނަށް އެއުރެންގެ (ޢަމަލުތަކުގެ) ހިސާބު ބެއްލެވުމުގެ ވަގުތު ގާތްވެއްޖެއެވެ. އެއުރެން ޣާފިލުވެ (އެކަމުން) އެއްކިބާވެގެންވާ ޙާލު ގައެވެ.","",""],["","","","ما يأتيهم من ذكر من ربهم محدث إلا استمعوه وهم يلعبون","އެއުރެން (އެއަށް) ފުރައްސާރަކުރާ ޙާލުގައި، އޭގެ އަޑުއަހާ ކަމުގައިނުވާ އައު އާޔަތެއް، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އެއުރެންނާ ހަމަޔަކަށް ނާދެތެވެ.","",""],["","","","لاهية قلوبهم وأسروا النجوى الذين ظلموا هل هذا إلا بشر مثلكم أفتأتون السحر وأنتم تبصرون","އެއުރެންގެ ހިތްތައް ޣާފިލު ވެގެންވާ ޙާލު ގައެވެ. އަދި އަނިޔާވެރިވި މީހުންކުޅަ ސައްލާތައް (އެއުރެންގެ މެދުގައި) ސިއްރުކުރޫއެވެ. (އެއުރެން ބުނޫއެވެ.) މިއީ (އެބަހީ: މުޙައްމަދުގެފާނީ) ހަމަތިޔަބައިމީހުންފަދަ އާދަމުގެދަރިޔަކު ކަމުގައިމެނުވީ ނުވެތެވެ. ފަހެ، ކަލޭމެން ދެކެދެނެތިބެ، ޖާދޫ ގަބޫލުކުރަނީ ހެއްޔެވެ؟","",""],["","","","قال ربي يعلم القول في السماء والأرض وهو السميع العليم","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އުޑާއި، ބިމުގައި ދެކެވޭހާ ވާހަކަތައް ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަދި އެކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","بل قالوا أضغاث أحلام بل افتراه بل هو شاعر فليأتنا بآية كما أرسل الأولون","އަދި ކިއެއްތަ! އެއުރެން ބުނޫއެވެ. (އެއީ) ހުވަފެނުގެ ހާސަރުތަކެކެވެ. އަދި ކިއެއްތަ! އެއީ އެކަލޭގެފާނު އަމިއްލަޔަށް ހެއްދެވި އެއްޗެކެވެ. އަދި ކިއެއްތަ! އެކަލޭގެފާނަކީ، ޅެންވެރިޔެކެވެ. ފަހެ (މުއުޖުޒާތް ތަކާއިގެން) ކުރީގެ ރަސޫލުން ފޮނުއްވެވިފަދައިން، އެކަލޭގެފާނުވެސް، ތިމަންމެންނަށް މުއުޖިޒާއެއް ގެނެސްދެއްވަ ބައްލަވާށެވެ!","",""],["","","","ما آمنت قبلهم من قرية أهلكناها أفهم يؤمنون","އެއުރެންގެ ކުރިން އީމާން ނުވި ކިތަންމެ ރަށެއްގެ އަހުލުވެރިންނެއް، ތިމަންރަސްކަލާނގެ ހަލާކު ކުރެއްވީމެވެ. ވީއިރު އެއުރެން، ފަހެ، އީމާން ވާނެ ހެއްޔެވެ؟","",""],["","","","وما أرسلنا قبلك إلا رجالا نوحي إليهم فاسألوا أهل الذكر إن كنتم لا تعلمون","ކަލޭގެފާނުގެ ކުރިންވެސް ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ވަހީ އިއްވަވާ ފިރިހެނުން މެނުވީ، ރަސޫލުކަމާއިގެން ނުފޮނުއްވަމެވެ. ފަހެ، ތިޔަބައިމީހުން ނުދަންނަކަމުގައިވާނަމަ، އިލްމުގެ އަހުލުވެރިންނާ ސުވާލުކުރާށެވެ!","",""],["","","","وما جعلناهم جسدا لا يأكلون الطعام وما كانوا خالدين","އަދި ކާނާކައިނޫޅޭ ހަށިތަކެއް ކަމުގައި، ތިމަންރަސްކަލާނގެ އެ ރަސޫލުން ނުލައްވަމެވެ. އަދި އަބަދަށް ދެމިތިބޭ ބަޔަކު ކަމުގައިވެސް އެބޭކަލުން ނުވެތެވެ.","",""],["","","","ثم صدقناهم الوعد فأنجيناهم ومن نشاء وأهلكنا المسرفين","ދެން ތިމަންރަސްކަލާނގެ އެބޭކަލުންނަށް ކުރެއްވި ވައުދު ފުއްދަވައި ދެއްވީމެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ އެބޭކަލުންނާއި، ތިމަންރަސްކަލާނގެ އިރާދަކުރެއްވި ބަޔަކު ސަލާމަތްކުރެއްވީމެވެ. އަދި (ފުރެދުމުގައި) ހައްދުފަހަނަޅައި ދިޔަމީހުން ހަލާކުކުރެއްވީމެވެ.","",""],["","","","لقد أنزلنا إليكم كتابا فيه ذكركم أفلا تعقلون","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށް އިބްރަތާއި، ނަސޭހަތް އޭގައި އެކުލެވިގެންވާ ފޮތެއް، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް ބާވައިލެއްވީމެވެ. ފަހެ، ތިޔަބައިމީހުން ނުވިސްނަނީ ހެއްޔެވެ؟","",""],["","","","وكم قصمنا من قرية كانت ظالمة وأنشأنا بعدها قوما آخرين","އަނިޔާވެރިވި ކިތައްކިތައް ރަށުގެ އަހުލުވެރިން ތިމަންރަސްކަލާނގެ ހަލާކު ކުރެއްވިން ހެއްޔެވެ؟ އަދި އެއުރެންގެ ފަހުން އެހެންބަޔަކު ތިމަންރަސްކަލާނގެ އުފެއްދެވީމެވެ.","",""],["","","","فلما أحسوا بأسنا إذا هم منها يركضون","ފަހެ، އެއުރެންނަށް ތިމަންރަސްކަލާނގެ އަޒާބު ގާތްވެއްޖެކަން އިޙުސާސް ވީހިނދު، އެހާރުން އެއުރެން އެތަނުން ފިލާންދުވެތެވެ.","",""],["","","","لا تركضوا وارجعوا إلى ما أترفتم فيه ومساكنكم لعلكم تسألون","(އެއުރެންނަށް އަންގަވާނެތެވެ.) ތިޔަބައިމީހުން ފިލާން ނުދުވާށެވެ! އަދި ތިޔަބައިމީހުން އެ ނިއުމަތް ތަކުގައި އަރާމުކުރާންތިބި ނިއުމަތް ތަކަށާއި، ތިޔަބައިމީހުންގެ ގެތަކަށް އެނބުރި ރުޖޫއަ ވާށެވެ! (އެއީ) ތިޔަބައިމީހުންނާ ސުވާލު ކުރައްވާނެ ކަމަށްޓަކައެވެ.","",""],["","","","قالوا يا ويلنا إنا كنا ظالمين","އެއުރެން ބުނޫއެވެ. އޭ ތިމަންމެންނަށް ހުރި ހަލާކެއްގެ ބޮޑުކަމާއެވެ! ހަމަކަށަވަރުން، ތިމަންމެންވީ އަނިޔާވެރިން ކަމުގައެވެ.","",""],["","","","فما زالت تلك دعواهم حتى جعلناهم حصيدا خامدين","ފަހެ، ކޮށާލައިފައިވާ ގޮވާންތަކެއް ފަދައިން، އަދި ނިވިފައިވާ އަޅިތަކެއް ފަދައިން ތިމަންރަސްކަލާނގެ އެއުރެން ލައްވައިފުމަށް ދާންދެން، އެއުރެންގެ އެ ގޮވުން ފިލައިނުދެތެވެ.","",""],["","","","وما خلقنا السماء والأرض وما بينهما لاعبين","ތިމަންރަސްކަލާނގެ އުޑާއި، ބިމާއި، އެ ދެމެދުގައި ވާހާތަކެތި، ކުޅިވަރެއްގެ ގޮތުގައެއް ނަހައްދަވަމެވެ.","",""],["","","","لو أردنا أن نتخذ لهوا لاتخذناه من لدنا إن كنا فاعلين","ތިމަންރަސްކަލާނގެ ކުޅިވަރެއްގެ ބޭނުންކުރެއްވުމަށް އިރާދަކުރެއްވިނަމަ، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ހަޒުރަތުން އެކަން އެގޮތަށް ހިއްޕެވީމުހެވެ. ތިމަންރަސްކަލާނގެ (އެކަންތައް) ކުރައްވާނެ ނަމައެވެ.","",""],["","","","بل نقذف بالحق على الباطل فيدمغه فإذا هو زاهق ولكم الويل مما تصفون","އަދި ކިއެއްތަ! ބާތިލުގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ހައްގު ފޮނުއްވަމެވެ. ދެން އެ ހައްގު، އެ ބާތިލު ހަލާކުކޮށްލަތެވެ. ފަހެ، އެހާރުން އެ ބާތިލު ނެތިހިނގައިދެތެވެ. އަދި (ﷲއާމެދު އެކަށީގެން ނުވާގޮތުން) ތިޔަބައިމީހުން ސިފަކޮށް، ބުނާބުނުންތަކުން ތިޔަބައިމީހުންނަށް ހަލާކު ހުށްޓެވެ.","",""],["","","","وله من في السماوات والأرض ومن عنده لا يستكبرون عن عبادته ولا يستحسرون","އަދި އުޑުތަކާއި، ބިމުގައިވާހާ ބަޔަކު މިލްކުވެގެންވަނީ، އެކަލާނގެއަށެވެ. އެކަލާނގެ ހަޒުރަތު ގައިވާ މަލާއިކަތުން، އެކަލާނގެއަށް އަޅުކަން ކުރުމަކަށް ބޮޑާވެއެއްނުގަނެތެވެ. އަދި ވަރުބައްޔެއްވެސް ނުމެވޭމެއެވެ.","",""],["","","","يسبحون الليل والنهار لا يفترون","އެ މަލާއިކަތުން ރެޔާދުވާލު ފޫހިވުމެއްނެތި (އެކަލާނގެ ހަޒުރަތަށް) ތަސްބީހަ ދަންނަވަތެވެ.","",""],["","","","أم اتخذوا آلهة من الأرض هم ينشرون","ނުވަތަ (މަރުވެފައިވާ މީހުން) އަލުން ދިރުވާނެ އިލާހުން ތަކެއް ބިމުން އެއުރެން ހިފީ ހެއްޔެވެ؟","",""],["","","","لو كان فيهما آلهة إلا الله لفسدتا فسبحان الله رب العرش عما يصفون","އެ ދެތާނގައި (އެބަހީ: އުޑާއި، ބިމުގައި) ﷲ މެނުވީ އިލާހުންތަކެއް ވީނަމަ، އެ ދެތަން ފަސާދަވެއްޖައީހެވެ. ފަހެ، އެއުރެން އެ ސިފަކޮށް ބުނާކަންތަކުން، ޢަރްޝުގެވެރި ﷲ، ހުސްތާހިރު ވެވޮޑިގެންވެއެވެ.","",""],["","","","لا يسأل عما يفعل وهم يسألون","އެކަލާނގެ ކުރައްވާ ކަމަކާމެދު، އެކަލާނގެއާ ސުވާލެއް ނުކުރެވޭހުށްޓެވެ. (އެއުރެންކުރާ ކަންތަކާމެދު) އެއުރެންނާ ސުވާލުކުރައްވާނެތެވެ.","",""],["","","","أم اتخذوا من دونه آلهة قل هاتوا برهانكم هذا ذكر من معي وذكر من قبلي بل أكثرهم لا يعلمون الحق فهم معرضون","ނުވަތަ އެކަލާނގެ ފިޔަވައި، އެއުރެން އިލާހުންތަކެއް ހިފީހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންގެ ދަލީލު ތިޔަބައިމީހުން ގެންނާށެވެ! މިއޮތީ، ތިމަންކަލޭގެފާނާ އެކުގައިވާ މީހުންގެ ފޮތާއި، ތިމަންކަލޭގެފާނުގެ ކުރީގެ މީހުންގެ ފޮތެވެ. އަދި ކިއެއްތަ! އެއުރެންކުރެ ގިނަމީހުން ހައްގެއް ނުދަނެތެވެ. ފަހެ، އެއުރެންނީ (އެއަށް) ފުރަގަސްދޭ ބަޔެކެވެ.","",""],["","","","وما أرسلنا من قبلك من رسول إلا نوحي إليه أنه لا إله إلا أنا فاعبدون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ މެނުވީ އިލާހަކު ނުވާކަމަށް އެބޭކަލަކަށް ވަހީ ނުކުރައްވާ އެއްވެސް ރަސޫލަކު، ކަލޭގެފާނުގެ ކުރިންވެސް ތިމަންރަސްކަލާނގެ ނުފޮނުއްވަމެވެ. ފަހެ، ތިޔަބައިމީހުން (ހަމައެކަނި) ތިމަންރަސްކަލާނގެއަށް އަޅުކަން ކުރާށެވެ!","",""],["","","","وقالوا اتخذ الرحمن ولدا سبحانه بل عباد مكرمون","އެއުރެން ބުނޫއެވެ. ރަޙްމާންވަންތަ ރަސްކަލާނގެ ދަރިކަލަކު ހިއްޕެވިއެވެ. އެކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! އަދި ކިއެއްތަ! (ﷲގެ ދަރިކަނބަލުންތަކެކޭ އެއުރެން ބުނާ މަލާއިކަތުންނަކީ) މާތް ކުރައްވާފައިވާ، އެކަލާނގެ އަޅުންތަކެކެވެ.","",""],["","","","لا يسبقونه بالقول وهم بأمره يعملون","އެބޭކަލުން އެކަލާނގެ ހަޒުރަތަށް އިސްވެބަހެއް ނުދަންނަވާނެތެވެ. އަދި އެބޭކަލުން ޢަމަލުކުރައްވާނީ، އެކަލާނގެ އަމުރުފުޅާ އެއްގޮތަށެވެ.","",""],["","","","يعلم ما بين أيديهم وما خلفهم ولا يشفعون إلا لمن ارتضى وهم من خشيته مشفقون","އެއުރެންގެ ކުރިމަތީގައިވާ ކަންތަކާއި، އެއުރެންގެ ފަހަތުގައިވާ ކަންތައް، އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަދި އެކަލާނގެ ރުހިވޮޑިގެންވާ އަޅަކަށް މެނުވީ، އެބޭކަލުން ޝަފާއަތް ތެރިއެއް ނުވާނެތެވެ. އަދި އެބޭކަލުންތިއްބަވާނީ، އެކަލާނގެ ހައިބަވަންތަކަމަށް ބިރުވެތިވެގެންނެވެ.","",""],["","","","ومن يقل منهم إني إله من دونه فذلك نجزيه جهنم كذلك نجزي الظالمين","އެއުރެންކުރެ ތިމަންނާއީ އެކަލާނގެ ފިޔަވައި އިލާހު އެކޭ ބުނާ މީހަކަށް، ފަހެ، ތިމަންރަސްކަލާނގެ ނަރަކައިން ޖަޒާ ދެއްވާހުށީމެވެ. އަނިޔާވެރިންނަށް ތިމަންރަސްކަލާނގެ ޖަޒާ ދެއްވަނީ އެފަދައިންނެވެ.","",""],["","","","أولم ير الذين كفروا أن السماوات والأرض كانتا رتقا ففتقناهما وجعلنا من الماء كل شيء حي أفلا يؤمنون","ހަމަކަށަވަރުން، އުޑުތަކާއި، ބިން، އެކަތިގަނޑަކަށްވެފައިވަނިކޮށް، ފަހެ، ތިމަންރަސްކަލާނގެ އެދޭތި ވަކިކޮށްލެއްވިކަން، ކާފިރުވި މީހުން ނުދަންނަނީ ހެއްޔެވެ؟ އަދި ތިމަންރަސްކަލާނގެ ދިރޭ ކޮންމެ އެއްޗެއް ފެނުން ހެއްދެވީމެވެ. ފަހެ، އެއުރެން އީމާން ނުވަނީ ހެއްޔެވެ؟","",""],["","","","وجعلنا في الأرض رواسي أن تميد بهم وجعلنا فيها فجاجا سبلا لعلهم يهتدون","އަދި އެއުރެންނާއިގެން އެ ބިން، ތެޅިފޮޅިގެންފާނެ ކަމަށްޓަކައި، ހަރުލައި ހުންނަ ފަރުބަދަތައް، ތިމަންރަސްކަލާނގެ ބިމުގައި ލެއްވީމެވެ. އަދި އެ ބިމުގައި، ބޮޑެތި ތަނަވަސް މަގުތައް ލެއްވީމެވެ. (އެއީ) އެއުރެންނަށް މަގު އެނގުމަށްޓަކެވެ.","",""],["","","","وجعلنا السماء سقفا محفوظا وهم عن آياتها معرضون","އަދި ރައްކާތެރިކުރައްވާފައިވާ ފުރާޅެއްކަމުގައި، ތިމަންރަސްކަލާނގެ އުޑު ލެއްވީމެވެ. އަދި އެއުރެންނަކީ އެތާނގެ (އިރުހަނދާއި، ތަރިތައްފަދަ) ހެކިތަކަށް ފުރަގަސްދޭ ބަޔެކެވެ.","",""],["","","","وهو الذي خلق الليل والنهار والشمس والقمر كل في فلك يسبحون","އެކަލާނގެއީ، ރޭގަނޑާއި ދުވާލު، އަދި އިރާއި ހަނދު ހެއްދެވި ރަސްކަލާނގެއެވެ. އެއިން ކޮންމެ އެއްޗެއްމެ، ފަލަކެއްގައި ހިނގަހިނގާ ހުރެތެވެ.","",""],["","","","وما جعلنا لبشر من قبلك الخلد أفإن مت فهم الخالدون","ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނުގެ ކުރިޔަކުންވެސް އާދަމުގެދަރިޔަކަށް (މަރުނުވެ) ދެމިހުރުމެއް ނުލައްވަމެވެ. ފަހެ، ކަލޭގެފާނު އަވަހާރަވެއްޖެނަމަ، އެއުރެންނީ ފަހެ، ދެމިތިބޭނޭ ބަޔެއް ހެއްޔެވެ؟","",""],["","","","كل نفس ذائقة الموت ونبلوكم بالشر والخير فتنة وإلينا ترجعون","ކޮންމެ ނަފްސަކީވެސް މަރުގެރަހަ ލިބިގަންނާނޭ އެއްޗެކެވެ. އަދި ނުބައިގޮތާއި ހެޔޮގޮތް މެދުވެރިކުރައްވައި، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން އިމްތިހާނުކުރައްވައި ގޮތްބައްލަވަމެވެ. އަދި ތިޔަބައިމީހުން ރުޖޫއަކުރައްވާހުށީ، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","وإذا رآك الذين كفروا إن يتخذونك إلا هزوا أهذا الذي يذكر آلهتكم وهم بذكر الرحمن هم كافرون","ކާފިރުވި މީހުން ކަލޭގެފާނު ދެކޭހިނދު، އެއުރެން ކަލޭގެފާނަށް ފުރައްސާރަނޫނީ ނުކުރެތެވެ. (އަދި ބުނެތެވެ.) ތިޔަބައިމީހުންގެ އިލާހު ންތަކަށް ކުޑައިމީސްބަސް ބުނާ މީހަކީ މިއީ ހެއްޔެވެ؟ އަދި އެއުރެންވަނީ ހަމަ، ރަޙްމާންވަންތަ ރަސްކަލާނގެ ފޮތަށް ކާފިރު ވެގެންނެވެ.","",""],["","","","خلق الإنسان من عجل سأريكم آياتي فلا تستعجلون","އިންސާނާ ހެއްދެވީ، އަވަސްކަން (އޭނާގެ ޠަބީޢަތުގައި) ލައްވާފައެވެ. ތިމަންރަސްކަލާނގެ އާޔަތްތައް ނިކަންހުރެ ތިޔަބައިމީހުންނަށް ދައްކަވާހުށީމެވެ. ފަހެ، ތިޔަބައިމީހުން، ތިމަންރަސްކަލާނގެ ހަޒުރަތުން އަވަސްވުން އެދި ނޫޅޭށެވެ!","",""],["","","","ويقولون متى هذا الوعد إن كنتم صادقين","އަދި އެއުރެން ބުނެތެވެ. ތިޔަބައިމީހުންނީ، ތެދުބުނާ ބަޔަކު ކަމުގައިވާނަމަ، ތިޔަ (ބުނާ އަޒާބުގެ) ވައުދު އަންނާނީ ކޮންއިރަކުން ހެއްޔެވެ؟","",""],["","","","لو يعلم الذين كفروا حين لا يكفون عن وجوههم النار ولا عن ظهورهم ولا هم ينصرون","ކާފިރުވި މީހުންނަށް އެއުރެންގެ ކުރިމަތިންނާއި، އެއުރެންގެ ފުރަގަހުން، އަލިފާނުގެ އަޒާބު ދުރުނުކުރެވޭހިނދު، އަދި އެއުރެންނަށް އެއްވެސް ފަރާތަކުން ނަސްރު ލިބުމެއް ނުވާހިނދު (އެކަން) އެނގޭނަމަ (އެއުރެން އެހެނެއް ނުބުނާނެ) ތެވެ.","",""],["","","","بل تأتيهم بغتة فتبهتهم فلا يستطيعون ردها ولا هم ينظرون","އަދި ކިއެއްތަ! އެއުރެންނަށް އެކަންތައް އަންނަހުށީ ކުއްލިއަކަށެވެ. އަދި އެކަންތައް އެއުރެން ހައިރާން ކޮށްލާނެތެވެ. ފަހެ، އެއުރެންނަށް އެކަންތައް ދުރުކުރުމަކަށް ކުޅަދާނަވެގެންނެއް ނުވެތެވެ. އަދި އެއުރެންނަކަށް މުހުލަތެއް ނުމެދެއްވާނެމެއެވެ.","",""],["","","","ولقد استهزئ برسل من قبلك فحاق بالذين سخروا منهم ما كانوا به يستهزئون","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ކުރީގެ ރަސޫލުންނަށްވެސް ފުރައްސާރަކުރިއެވެ. ފަހެ، އެ ރަސޫލުންނަށް ފުރައްސާރަކޮށް އުޅުނުމީހުން ކުރަމުންގެންދިޔަ ފުރައްސާރައިގެ ކަންތައް (އެބަހީ: އެކަމުގެ ކޯފާއާއި އަޒާބު) އެއުރެން ވަށައިލިއެވެ.","",""],["","","","قل من يكلؤكم بالليل والنهار من الرحمن بل هم عن ذكر ربهم معرضون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ރެޔާއިދުވާލުގައި، ރަޙްމާންވަންތަ ރަސްކަލާނގެ ކޯފާއިން ތިޔަބައިމީހުން ރައްކާތެރިކުރާނީ ކާކުހެއްޔެވެ؟ އަދި ކިއެއްތަ! އެއުރެންނަކީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ ފޮތަށް ފުރަގަސްދޭ ބަޔެކެވެ.","",""],["","","","أم لهم آلهة تمنعهم من دوننا لا يستطيعون نصر أنفسهم ولا هم منا يصحبون","ނުވަތަ ތިމަންރަސްކަލާނގެ އަޒާބެއުރެންގެ ކިބައިން ދުރުކޮށްދޭނެ އިލާހުން ތަކެއް، އެއުރެންނަށް ވޭހެއްޔެވެ؟ އެ ތަކެއްޗަށް އޭގެ އަމިއްލަ ނަފްސަށް ނަސްރު ދިނުމަކަށް ކުޅަދާނަވެގެނެއްނުވެތެވެ. އަދި ތިމަންރަސްކަލާނގެ އަޒާބުން މިންޖުކޮށްދޭނޭ ބަޔަކުވެސް އެ ތަކެއްޗާއެކުގައި ނުމެވާހުށިމެއެވެ.","",""],["","","","بل متعنا هؤلاء وآباءهم حتى طال عليهم العمر أفلا يرون أنا نأتي الأرض ننقصها من أطرافها أفهم الغالبون","އަދި ކިއެއްތަ! މިބައިމީހުންނާއި، އެއުރެންގެ މައިންބަފައިން ދިގު އުމުރަކަށް ދާނދެން ދުނިޔޭގެ ނިއުމަތުގައި ތިމަންރަސްކަލާނގެ ލެހެއްޓެވީމެވެ. ފަހެ، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ބިމުގެ ހުރިހާ ފަރާތަކުން އުނިކުރައްވަމުން ގެންދަވާކަން، އެއުރެންނަށް ނޭނގެނީ ހެއްޔެވެ؟ ފަހެ، ގަދަވާނެ ބަޔަކީ އެއުރެން ހެއްޔެވެ؟","",""],["","","","قل إنما أنذركم بالوحي ولا يسمع الصم الدعاء إذا ما ينذرون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނު ތިޔަބައިމީހުންނަށް އިންޒާރުކުރައްވާކަން ކަށަވަރީ، ވަހީ އިންނެވެ. އަދި ބީރުމީހުން، އެއުރެންނަށް އިންޒާރުކުރައްވާ ހިނދު، ގޮވައިލާއަޑެއް ނާހާނެތެވެ.","",""],["","","","ولئن مستهم نفحة من عذاب ربك ليقولن يا ويلنا إنا كنا ظالمين","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އަޒާބުން ކިތަންމެ ކުޑަ މިންވަރެއް އެއުރެންގައި ބީހުނަސް، ހަމަކަށަވަރުން، އެއުރެން ބުނާނެތެވެ. އޭ ތިމަންމެންނަށްހުރި ހަލާކެއްގެ ބޮޑުކަމާއެވެ! ހަމަކަށަވަރުން، ތިމަންމެން އަނިޔާވެރިން ކަމުގައިވީމުއެވެ.","",""],["","","","ونضع الموازين القسط ليوم القيامة فلا تظلم نفس شيئا وإن كان مثقال حبة من خردل أتينا بها وكفى بنا حاسبين","ތިމަންރަސްކަލާނގެ ގިޔާމަތް ދުވަހުން ޢަދުލުވެރިކަމުގެ ތިލަފަތްތައް ގާއިމުކުރައްވާހުށީމެވެ. ފަހެ، އެއްވެސް ނަފްސަކަށް، އެއްވެސް ކަމަކުން ބޭއިންސާފެއް ނުކުރައްވާހުށްޓެވެ. އަދި އެއީ ރެވިއޮށްޓަރެއްގެ ބަރުދަން ކަމުގައިވިޔަސް، އެ، ގެންނަވާހުށީމެވެ. ހިސާބު ބައްލަވާ ކަލަކު ކަމުގައި ތިމަންރަސްކަލާނގެ ފުދެއެވެ.","",""],["","","","ولقد آتينا موسى وهارون الفرقان وضياء وذكرا للمتقين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށާއި، ހާރޫނުގެފާނަށް ހައްގާއި، ބާތިލު ވަކިކުރަނިވި ފޮތް (އެބަހީ: ތައުރާތު) ދެއްވީމެވެ. ތަގުވާވެރިންނަށް، އަލިކަމެއް ކަމުގައްޔާއި، ހަނދާންކޮށްދިނުމެއް ކަމުގައެވެ.","",""],["","","","الذين يخشون ربهم بالغيب وهم من الساعة مشفقون","އެއުރެންނަކީ އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ޣައިބުގައި ބިރުވެތިވާ މީހުންނެވެ. އަދި އެއުރެންވަނީ، ގިޔާމަތް ދުވަހަށް ބިރުވެތިވެގެންނެވެ.","",""],["","","","وهذا ذكر مبارك أنزلناه أفأنتم له منكرون","މި ގުރްއާނަކީ، ބަރަކާތް ތެރިވެގެންވާ ހަނދާންކޮށް ދިނުމެކެވެ. ތިމަންރަސްކަލާނގެ އެ ފޮތް ބާވައިލެއްވީމެވެ. ފަހެ، ތިޔަބައިމީހުން އެ ފޮތަށް އިންކާރުކުރަނީ ހެއްޔެވެ؟","",""],["","","","ولقد آتينا إبراهيم رشده من قبل وكنا به عالمين","އަދި ހަމަކަށަވަރުން، މީގެކުރިން އިބްރާހީމްގެފާނަށް، ތިމަންރަސްކަލާނގެ ހެޔޮ ވިސްނުމާއި، ބުއްދިވެރިކަން ދެއްވީމެވެ. އަދި އެކަލޭގެފާނާމެދު ތިމަންރަސްކަލާނގެ މޮޅަށްދެނެވޮޑިގެންވަމެވެ.","",""],["","","","إذ قال لأبيه وقومه ما هذه التماثيل التي أنتم لها عاكفون","އެކަލޭގެފާނުގެ ބައްޕާއަށާއި، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް އެކަލޭގެފާނު ވިދާޅުވިހިނދު، ހަނދުމަކުރާށެވެ! ތިޔަބައިމީހުން އަޅުކަންކުރަން ތިޔަތިބީ، ކޮން ބުދުތަކަކަށް ހެއްޔެވެ؟","",""],["","","","قالوا وجدنا آباءنا لها عابدين","އެއުރެން ދެންނެވޫއެވެ. ތިމަންމެންގެ ކާބަފައިން، އެ ތަކެއްޗަށް އަޅުކަންކުރާތީ ތިމަންމެން ދުށީމުއެވެ.","",""],["","","","قال لقد كنتم أنتم وآباؤكم في ضلال مبين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނާއި، ތިޔަބައިމީހުންގެ ކާބަފައިންވަނީ، ފާޅުވެގެންވާ މަގު ފުރެދުމެއްގައެވެ.","",""],["","","","قالوا أجئتنا بالحق أم أنت من اللاعبين","އެއުރެން ދެންނެވޫއެވެ. ކަލޭގެފާނު ތިޔަވަޑައިގަތީ، ހައްގު ތެދުމަގާއިގެން ހެއްޔެވެ؟ ނުވަތަ ކަލޭގެފާނުވަނީ، ކުޅޭމީހުންގެ ތެރެއިން ހެއްޔެވެ؟","",""],["","","","قال بل ربكم رب السماوات والأرض الذي فطرهن وأنا على ذلكم من الشاهدين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަދި ކިއެއްތަ! ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއީ، އުޑުތަކާއި، ބިމުގެ ވެރިރަސްކަލާނގެއެވެ. އެކަލާނގެއީ، އިސްވެދިޔަ މިސާލަކާނުލައި، އެ ތަކެތި ހެއްދެވި ރަސްކަލާނގެއެވެ. އަދި ތިމަންކަލޭގެފާނު ވަނީ، އެކަމުގެ މައްޗަށް ހެކިވާމީހުންގެ ތެރެއިންނެވެ.","",""],["","","","وتالله لأكيدن أصنامكم بعد أن تولوا مدبرين","އަދި ﷲ ގަންދީ ހުވާ ކުރައްވަމެވެ. ތިޔަބައިމީހުން ފުރަގަސްދީ ދިއުމަށްފަހު، ތިޔަބައިމީހުންގެ ބުދުތައް ހަލާކުކޮށްލުމަށް، ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނު ގޮތެއް ރާއްވަވާހުށީމެވެ.","",""],["","","","فجعلهم جذاذا إلا كبيرا لهم لعلهم إليه يرجعون","ފަހެ، އެއުރެންގެ ބޮޑު ބުދު ފިޔަވައި، އެކަލޭގެފާނު އެ ބުދުތައް މުގުރުއްވިއެވެ. (އެއީ) އެއުރެން އޭގެކައިރިޔަށް އައުމަށްޓަކައެވެ.","",""],["","","","قالوا من فعل هذا بآلهتنا إنه لمن الظالمين","އެއުރެން ބުނޫއެވެ. ތިމަންމެންގެ އިލާހު ންތަކަށް މިހެންހެދީ ކާކުހެއްޔެވެ؟ ހަމަކަށަވަރުން، އެ މީހަކުވަނީ އަނިޔާވެރިންގެ ތެރެއިންނެވެ.","",""],["","","","قالوا سمعنا فتى يذكرهم يقال له إبراهيم","އެއުރެން ބުނޫއެވެ. އިބްރާހީމް އޭ ކިޔާ ޒުވާނަކު އެ އެއްޗިއްސަށް އައިބު ބަސް ބުނާއަޑު ތިމަންމެންއެހީމުއެވެ.","",""],["","","","قالوا فأتوا به على أعين الناس لعلهم يشهدون","އެއުރެން ބުނޫއެވެ. ފަހެ، މީސްތަކުންގެ ކުރިމައްޗަށް އޭނާ ގެންނާށެވެ! (އެއީ) އެއުރެން ހެކިވުމަށްޓަކައެވެ.","",""],["","","","قالوا أأنت فعلت هذا بآلهتنا يا إبراهيم","އެއުރެން ބުނޫއެވެ. އޭ އިބްރާހީމްގެފާނެވެ! ތިމަންމެންގެ އިލާހު ންތަކަށް މިހެން ހެއްދެވީ ކަލޭގެފާނުތޯއެވެ؟","",""],["","","","قال بل فعله كبيرهم هذا فاسألوهم إن كانوا ينطقون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަދި ކިއެއްތަ! އެކަންތައް ކުޅައީ އެ ބުދުތަކުގެ ތެރެއިން މިހިރަބޮޑުބުދެވެ. ފަހެ، އެ ބުދުތައް ވާހަކަ ދައްކާ ކަމުގައިވާނަމަ، ތިޔަބައިމީހުން އެބުދުތަކާ ސުވާލުކުރާށެވެ!","",""],["","","","فرجعوا إلى أنفسهم فقالوا إنكم أنتم الظالمون","ފަހެ، އެއުރެން، އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް ރުޖޫއަ ވެއްޖައޫއެވެ. ދެން އެއުރެން ބުނޫއެވެ. ހަމަކަށަވަރުން، އަނިޔާވެރި ބަޔަކީ، ހަމަތިޔަބައި މީހުންނެވެ.","",""],["","","","ثم نكسوا على رءوسهم لقد علمت ما هؤلاء ينطقون","ދެން އެއުރެންނަށް އިސްދަށަށް ޖެހެވުނެވެ. (އަދި ބުނޫއެވެ.) ހަމަކަށަވަރުން، މި ތަކެތި ވާހަކަ ނުދައްކާކަން ކަލޭގެފާނަށް އެނގިވަޑައިގެންފައިވާނެތެވެ.","",""],["","","","قال أفتعبدون من دون الله ما لا ينفعكم شيئا ولا يضركم","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ފަހެ، ތިޔަބައިމީހުންނަށް އެއްވެސް ފައިދާއެއް ނުކުރާ، އަދި ގެއްލުމެއްވެސް ނުދޭ އެއްޗެހިތަކަކަށް ﷲ ފިޔަވައި، ތިޔަބައިމީހުން އަޅުކަންކުރަނީ ހެއްޔެވެ؟","",""],["","","","أف لكم ولما تعبدون من دون الله أفلا تعقلون","ތިޔަބައިމީހުންނަށާއި، ﷲ ފިޔަވައި ތިޔަބައިމީހުން އަޅުކަންކުރާ ތަކެއްޗަށް، ހަޑިހުތުރުކަންހުށްޓެވެ. ފަހެ، ތިޔަބައިމީހުންނަކަށް ނުވިސްނޭހެއްޔެވެ؟","",""],["","","","قالوا حرقوه وانصروا آلهتكم إن كنتم فاعلين","އެއުރެން ބުނޫއެވެ. ތިޔަބައިމީހުން ކަމެއްކުރަނީ ކަމުގައިވާނަމަ، އެކަލޭގެފާނު އަންދައިލާށެވެ! އަދި ތިޔަބައިމީހުންގެ އިލާހު ންތަކަށް ނަސްރު ދޭށެވެ!","",""],["","","","قلنا يا نار كوني بردا وسلاما على إبراهيم","(ދެން އެއުރެން އެކަލޭގެފާނު އަލިފާނަށް އެއްލިހިނދު) ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވީމެވެ. އޭ އަލިފާނާއެވެ! އިބްރާހީމްގެފާނުގެ މައްޗަށް ފިނިކަމެއް ކަމުގައްޔާއި، އަމާންކަމެއްކަމުގައި ވާށެވެ!","",""],["","","","وأرادوا به كيدا فجعلناهم الأخسرين","އެއުރެން އެކަލޭގެފާނު ހަލާކުކޮށްލުމަށް މަކަރުވެރި ރޭވުމެއް ރޭވޫއެވެ. ފަހެ، އެންމެ ބޮޑަށް ގެއްލެނިވެގެންވާ ބަޔަކުކަމުގައި ތިމަންރަސްކަލާނގެ އެއުރެން ލެއްވީމެވެ.","",""],["","","","ونجيناه ولوطا إلى الأرض التي باركنا فيها للعالمين","އަދި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނާއި، ލޫޠުގެފާނު ސަލާމަތްކުރައްވައި، އާލަމް ތަކަށްޓަކައި، ތިމަންރަސްކަލާނގެ ބަރަކާތްލެއްވި ބިމަށް ފޮނުއްވީމެވެ.","",""],["","","","ووهبنا له إسحاق ويعقوب نافلة وكلا جعلنا صالحين","އަދި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް (އެބަހީ: އިބްރާހީމްގެފާނަށް) އިސްޙާގުގެފާނު ދެއްވީމެވެ. އަދި އިތުރަށް ޔައުގޫބުގެފާނު ދެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އެ ހުރިހާ ބޭކަލުންނަކީ، ސާލިހުން ކަމުގައި ލެއްވީމެވެ.","",""],["","","","وجعلناهم أئمة يهدون بأمرنا وأوحينا إليهم فعل الخيرات وإقام الصلاة وإيتاء الزكاة وكانوا لنا عابدين","އަދި ތިމަންރަސްކަލާނގެ އަމުރުފުޅަށް ތެދުމަގު ދައްކަވާ އިމާމުންކަމުގައި، ތިމަންރަސްކަލާނގެ އެބޭކަލުން ލެއްވީމެވެ. އަދި ހެޔޮކަންތައް ކުރެއްވުމަށާއި، ނަމާދު ގާއިމުކުރެއްވުމަށާއި، ޒަކާތްދެއްވުމަށް، ތިމަންރަސްކަލާނގެ އެބޭކަލުންނަށް ވަހީކުރެއްވީމެވެ. އަދި ހަމައެކަނި، ތިމަންރަސްކަލާނގެއަށް އަޅުކަންކުރާބަޔަކު ކަމުގައި އެބޭކަލުން ވޫއެވެ.","",""],["","","","ولوطا آتيناه حكما وعلما ونجيناه من القرية التي كانت تعمل الخبائث إنهم كانوا قوم سوء فاسقين","ލޫޠުގެފާނަށް ތިމަންރަސްކަލާނގެ ހިކުމަތް ތެރިކަމާއި، އިލްމު ދެއްވީމެވެ. އަދި ނުބައި ފާފަތައް ކޮށްއުޅުނު ރަށުގެ (މީހުންގެ) ކިބައިން، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނު ސަލާމަތްކުރެއްވީމެވެ. ހަމަކަށަވަރުން، އެއުރެންވީ، ނުބައިކަމުގެ އަހުލުވެރި، ފާސިގު ބަޔަކު ކަމުގައެވެ.","",""],["","","","وأدخلناه في رحمتنا إنه من الصالحين","އަދި ތިމަންރަސްކަލާނގެ ރަހުމަތްގެ ތެރެޔަށް އެކަލޭގެފާނު ވެއްދެވީމެވެ. ހަމަކަށަވަރުން، އެކަލޭގެފާނުވަނީ، ސާލިހުންގެ ތެރެއިންނެވެ.","",""],["","","","ونوحا إذ نادى من قبل فاستجبنا له فنجيناه وأهله من الكرب العظيم","އަދި އޭގެކުރިން، ނޫޙުގެފާނު (ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް) ދުއާކުރެއްވިހިނދު، ހަނދުމަކުރާށެވެ! ފަހެ، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް އިޖާބަދެއްވީމެވެ. އަދި ބޮޑުވެގެންވާނުރައްކަލުން އެކަލޭގެފާނާއި، އެކަލޭގެފާނުގެ އަހުލުވެރިން ސަލާމަތްކުރެއްވީމެވެ.","",""],["","","","ونصرناه من القوم الذين كذبوا بآياتنا إنهم كانوا قوم سوء فأغرقناهم أجمعين","އަދި ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުރި މީހުންގެ ކިބައިން (އެކަލޭގެފާނު ސަލާމަތްކުރައްވައި) ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ނަސްރު ދެއްވީމެވެ. ހަމަކަށަވަރުން، އެއުރެންވީ ނުބައިކަމުގެ އަހުލުވެރި ބަޔަކު ކަމުގައެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ އެއުރެން އެންމެން ޣަރަގުކުރެއްވީމެވެ.","",""],["","","","وداوود وسليمان إذ يحكمان في الحرث إذ نفشت فيه غنم القوم وكنا لحكمهم شاهدين","އަދި ދާވޫދުގެފާނާއި، ސުލައިމާނުގެފާނު ހަނދުމަކުރާށެވެ! ގައުމުގެމީހުންގެ ބަކަރިތަކެއް ދަނޑަކަށްވަދެ، ރޭގަނޑުގައި ހުއިހެފި މަސްއަލާގައި، އެ ދެބޭކަލުން (ދެގޮތަށް) ހުކުމްކުރެއްވި ހިނދެވެ. އަދި އެ ދެބޭކަލުން ކުރެއްވި ހުކުމްގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ހެކިވެވޮޑިގެންވަމެވެ.","",""],["","","","ففهمناها سليمان وكلا آتينا حكما وعلما وسخرنا مع داوود الجبال يسبحن والطير وكنا فاعلين","ފަހެ، ތިމަންރަސްކަލާނގެ ސުލައިމާނުގެފާނަށް އެ ހުކުމް ވިސްނައިދެއްވީމެވެ. އަދި އެއިން ކޮންމެ ބޭކަލަކަށްމެ ހިކުމަތާއި، އިލްމު ދެއްވީމެވެ. އަދި ދާވޫދުގެފާނާއެކުގައި، ތަސްބީހަ ކިޔާ ތަކެތިކަމުގައި، ފަރުބަދަތަކާއި، ދޫނިތައްލެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ (އެ ހުރިހާ ކަމެއް) ކުރެއްވީމެވެ.","",""],["","","","وعلمناه صنعة لبوس لكم لتحصنكم من بأسكم فهل أنتم شاكرون","އަދި ހަނގުރާމައިގައި، ތިޔަބައިމީހުން ރައްކާތެރިކުރުމަށް، ތިޔަބައިމީހުންނަށްޓަކައި، ދަހަނާހަދާނޭގޮތް ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް އުނގަންނައިދެއްވީމެވެ. ފަހެ، ތިޔަބައިމީހުންނީ ޝުކުރުކުރާ ބަޔެއް ހެއްޔެވެ؟","",""],["","","","ولسليمان الريح عاصفة تجري بأمره إلى الأرض التي باركنا فيها وكنا بكل شيء عالمين","އަދި ތިމަންރަސްކަލާނގެ، ސުލައިމާނުގެފާނަށް ވައިރޯޅި ގަދަޔަށްޖެހޭ ގޮތުގައި (އެ) ޚިދުމަތް ތެރި ކުރެއްވީމެވެ. ތިމަންރަސްކަލާނގެ އެ ބިމުގައި، ބަރަކާތް ލެއްވި ބިމަށް، އެކަލޭގެފާނުގެ އަމުރުފުޅަށް، އެ ވައިރޯޅި ހިނގައިދާގޮތުގައެވެ. އަދި ތިމަންރަސްކަލާނގެ ކޮންމެކަމެއް ދެނެވޮޑިގެންވަމެވެ.","",""],["","","","ومن الشياطين من يغوصون له ويعملون عملا دون ذلك وكنا لهم حافظين","އަދި ޝައިތާނުންގެ ތެރެއިން، އެކަލޭގެފާނަށްޓަކައި، ފީނާބަޔަކު (ޚިދުމަތް ތެރި ކުރެއްވީމެވެ.) އަދި އެނޫން އެތައް މަސައްކަތެއް އެބަޔަކު ކުރެތެވެ. އަދި ތިމަންރަސްކަލާނގެ އެ ބަޔަކު ބަލަހައްޓަވައި، ރައްކާތެރިކުރެއްވީމެވެ.","",""],["","","","وأيوب إذ نادى ربه أني مسني الضر وأنت أرحم الراحمين","އަދި އައްޔޫބުގެފާނު، އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް ދުއާކުރެއްވި ހިނދު، ހަނދުމަކުރާށެވެ! ހަމަކަށަވަރުން، މިއަޅާޔަށް ދަތިކަމާއި، އުނދަގޫ ޖެހިއްޖެއެވެ. އަދި އިބަރަސްކަލާނގެއީ، ރަހުމަތް ލައްވާ، އެންމެ ރަހުމަތްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","فاستجبنا له فكشفنا ما به من ضر وآتيناه أهله ومثلهم معهم رحمة من عندنا وذكرى للعابدين","ފަހެ، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް އިޖާބަދެއްވައި، އެކަލޭގެފާނަށް ޖެހިފައިވާ ދަތި ޙާލު ފިއްލަވައި، އަދި އެކަލޭގެފާނަށް އެކަލޭގެފާނުގެ އަހުލްނާއި، އެ އަހުލުންނާއެކު ހަމަ އެފަދަ އަހުލުން ދެއްވީމެވެ. ތިމަންރަސްކަލާނގެ ހަޒުރަތުން ލެއްވި ރަހުމަތެއް ކަމުގައެވެ. އަދި އަޅުކަންކުރާ މީހުންނަށް، ހަނދާންކޮށްދިނުމެއް ކަމުގައެވެ.","",""],["","","","وإسماعيل وإدريس وذا الكفل كل من الصابرين","އަދި އިސްމާޢީލުގެފާނާއި، އިދްރީސްގެފާނާއި، ޛުލްކިފްލިގެފާނު ހަނދުމަކުރާށެވެ! އެއިން ކޮންމެ ބޭކަލަކުވަނީ، ކެތްތެރިންގެ ތެރެއިންނެވެ.","",""],["","","","وأدخلناهم في رحمتنا إنهم من الصالحين","އަދި އެބޭކަލުން ތިމަންރަސްކަލާނގެ ރަހުމަތްގެ ތެރެޔަށް ވެއްދެވީމެވެ. ހަމަކަށަވަރުން، އެބޭކަލުންވަނީ، ސާލިހުންގެ ތެރެއިންނެވެ.","",""],["","","","وذا النون إذ ذهب مغاضبا فظن أن لن نقدر عليه فنادى في الظلمات أن لا إله إلا أنت سبحانك إني كنت من الظالمين","އަދި ޛުއްނޫނި (އެބަހީ: ޔޫނުސްގެފާނު) ހަނދުމަކުރާށެވެ! އެކަލޭގެފާނު (ގައުމުގެ މީހުންދެކެ) ކޯފާވެގެން ވަޑައިގަތް ހިނދެވެ. ފަހެ، އެކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ އުގޫބާތެއް ނުދެއްވާނެކަމަށް ހީކުރެއްވިއެވެ. ފަހެ، އެކަލޭގެފާނު އަނދިރިތަކުގެ ތެރޭގައި (މަހުގެ ބަނޑުގައި) ދުއާކުރެއްވިއެވެ. އިބަރަސްކަލާނގެ މެނުވީ، އިލާހަކު ނެތެވެ. އިބަރަސްކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! ހަމަކަށަވަރުން، އަނިޔާވެރިންގެ ތެރެއިން މި އަޅާވީމެވެ.","",""],["","","","فاستجبنا له ونجيناه من الغم وكذلك ننجي المؤمنين","ފަހެ، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް އިޖާބަ ދެއްވީމެވެ. އަދި ދަތިކަމާއި، މޮޅިވެރިކަމުން އެކަލޭގެފާނު ސަލާމަތްކުރެއްވީމެވެ. އަދި އެފަދައިން ތިމަންރަސްކަލާނގެ މުއުމިނު ތަކުން ސަލާމަތްކުރައްވަމެވެ.","",""],["","","","وزكريا إذ نادى ربه رب لا تذرني فردا وأنت خير الوارثين","އަދި ޒަކަރިއްޔާގެފާނު ހަނދުމަކުރާށެވެ! އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް ދުއާކުރެއްވި ހިނދެވެ. އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! މި އަޅާޔަކީ (ދަރިޔަކުނެތް) އެކަނިވެރި މީހެއްކަމުގައި ނުލައްވާނދޭވެ! އަދި އިބަރަސްކަލާނގެއީ، ދިރިދެމިވޮޑިގެންވާ، އެންމެ ހެޔޮ ރަސްކަލާނގެއެވެ.","",""],["","","","فاستجبنا له ووهبنا له يحيى وأصلحنا له زوجه إنهم كانوا يسارعون في الخيرات ويدعوننا رغبا ورهبا وكانوا لنا خاشعين","ފަހެ، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް އިޖާބަދެއްވީމެވެ. އަދި އެކަލޭގެފާނަށް ޔަޙްޔާގެފާނު ދެއްވީމެވެ. އަދި އެކަލޭގެފާނަށް އެކަލޭގެފާނުގެ އަނބިކަނބަލުން (ދަރިމައިވާގޮތަށް) ރަނގަޅުކޮށްދެއްވީމެވެ. ހަމަކަށަވަރުން، އެބޭކަލުން ހެޔޮކަންތަކަށް އަވަސްވެ، އަދި ތިމަންރަސްކަލާނގެއަށް އެދުމާއި، ބިރުވެތިކަމާއެކު، ދުއާކުރައްވާ ކަމުގައިވިއެވެ. އަދި ތިމަންރަސްކަލާނގެއަށް މަޑުމައިތިރިވާ ބަޔަކުކަމުގައި އެބޭކަލުންވޫއެވެ.","",""],["","","","والتي أحصنت فرجها فنفخنا فيها من روحنا وجعلناها وابنها آية للعالمين","އަދި އެކަމަނާގެ ފަރުޖު ރައްކާތެރިކުރެއްވި ކަމަނާ (އެބަހީ: މަރިޔަމްގެފާނު) ހަނދުމަކުރާށެވެ! ފަހެ، ތިމަންރަސްކަލާނގެ ރޫޙުފުޅުން އެ ކަމަނާއަށް ފުމެލެއްވީމެވެ. އަދި އެކަމަނާއާއި، އެ ކަމަނާގެ ދަރިކަލުން ޢީސާގެފާނު، އާލަމް ތަކަށްވާ ހެތްކެއްކަމުގައި، ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ.","",""],["","","","إن هذه أمتكم أمة واحدة وأنا ربكم فاعبدون","ހަމަކަށަވަރުން، މިއީ، އެއް އުއްމަތެއް ކަމުގައިވާ ތިޔަބައިމީހުންގެ އުއްމަތެވެ. އަދި ތިމަންރަސްކަލާނގެއީ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއެވެ. ފަހެ، ތިޔަބައިމީހުން ތިމަންރަސްކަލާނގެއަށް އަޅުކަންކުރާށެވެ!","",""],["","","","وتقطعوا أمرهم بينهم كل إلينا راجعون","އެއުރެންގެ މެދުގައި، ދީނުގެ ކަންތައްތަކާމެދު ޚިލާފުވެ، ވަކިވަކިވެގަތޫއެވެ. އެއިން ކޮންމެ ބަޔަކީވެސް، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ރުޖޫއަ ވާނޭ ބަޔެކެވެ.","",""],["","","","فمن يعمل من الصالحات وهو مؤمن فلا كفران لسعيه وإنا له كاتبون","ފަހެ، އީމާން ވެހުރެ ސާލިހު ޢަމަލުތައް ކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާގެ ޢަމަލުގެއްލިއެއް ނުދާނެތެވެ. އަދި އެމީހާގެ ޢަމަލުތައް ތިމަންރަސްކަލާނގެ ލިޔުއްވާހުށީމެވެ.","",""],["","","","وحرام على قرية أهلكناها أنهم لا يرجعون","ތިމަންރަސްކަލާނގެ ހަލާކުކުރެއްވި ރަށެއްގެ އަހުލުވެރިން އެނބުރި (ދުނިޔެއަށް) ނާންނާނެކަމަށް އެއުރެންގެ މައްޗަށް ކަނޑައަޅުއްވާފައިވެއެވެ.","",""],["","","","حتى إذا فتحت يأجوج ومأجوج وهم من كل حدب ينسلون","ޔައުޖޫޖު މައުޖޫޖު ބާގައިމީހުން ވީއްލި، ހުރިހާ އުސްތަންތަނުން ފައިބައިގެން އެއުރެން އަތުވެއްޖައުމަށް ދާނދެނެވެ.","",""],["","","","واقترب الوعد الحق فإذا هي شاخصة أبصار الذين كفروا يا ويلنا قد كنا في غفلة من هذا بل كنا ظالمين","އަދި ހައްގު ތެދު ވައުދު (އެބަހީ: ގިޔާމަތް ވުމުގެ ވަގުތު) ގާތްވެއްޖެއެވެ. ފަހެ، އެހާރުން ކާފިރުވި މީހުން (ބިރުން) ލޯތައް ބޮޑުވެފައިވާނެތެވެ. (އަދި ބުނާނެތެވެ.) އޭ ތިމަންމެންނަށްހުރި ހަލާކެއްގެބޮޑުކަމާއެވެ! ހަމަކަށަވަރުން، ތިމަންމެންތިބީ، މިކަންތައްތަކާމެދު ޣާފިލުކަމެއްގައެވެ. އަދި ކިއެއްތަ! ތިމަންމެންވީ، އަނިޔާވެރި ބަޔެއްކަމުގައެވެ.","",""],["","","","إنكم وما تعبدون من دون الله حصب جهنم أنتم لها واردون","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނާއި، ﷲ ފިޔަވައި ތިޔަބައިމީހުން އަޅުކަންކުރާ ތަކެއްޗަކީ، ނަރަކައިގެ ދަރެވެ. ތިޔަބައިމީހުން އެތަނަށް ވަންނަހުށްޓެވެ.","",""],["","","","لو كان هؤلاء آلهة ما وردوها وكل فيها خالدون","މި ތަކެއްޗަކީ، އިލާހުންތަކެއް ކަމުގައިވީނަމަ، އެ ތަކެތި އެ ތަނަކަށް ނުވަނީހެވެ. އަދި އެހުރިހާތަކެތި އެތާނގައި ދެމިތިބޭނެތެވެ.","",""],["","","","لهم فيها زفير وهم فيها لا يسمعون","އެތާނގައި އެއުރެން ނޭވާލާ އަޑުފަށްގަނޑު ހުންނާނެތެވެ. އަދި އެއުރެންނަކަށް އެތާނގައި އަޑެއް ނީވޭނެތެވެ.","",""],["","","","إن الذين سبقت لهم منا الحسنى أولئك عنها مبعدون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ހަޒުރަތުން އެ ބަޔަކަށް ބާއްޖަވެރިކަން އިސްވެގޮސްފައިވާ މީހުން (ދަންނާށެވެ!) އެއުރެންވަނީ، އެ ނަރަކަޔާ ދުރުކުރައްވާފައެވެ.","",""],["","","","لا يسمعون حسيسها وهم في ما اشتهت أنفسهم خالدون","އެއުރެންނަކަށް އެތާނގެ އަލިފާނުގެ އަޑެއްވެސް ނީވޭނެތެވެ. އަދި އެއުރެން ހިތްއެދޭ ކަންތައްތަކުގައި (ސުވަރުގޭގައި) އެއުރެން ދެމިތިބޭނެތެވެ.","",""],["","","","لا يحزنهم الفزع الأكبر وتتلقاهم الملائكة هذا يومكم الذي كنتم توعدون","އެންމެބޮޑު ބިރުވެރިކަން (އެބަހީ: ގިޔާމަތް ދުވަހުގެ ބިރުވެރިކަން) އެއުރެންނަކަށް އެއްވެސް ހިތާމައެއް ނުދޭހުށްޓެވެ. އަދި މަލާއިކަތުން އެއުރެންނާ ބައްދަލުކުރައްވާނެތެވެ. (އަދި ވިދާޅުވާނެތެވެ.) ތިޔަބައިމީހުންނަށް ވައުދުކުރައްވާ ކަމުގައިވީ ދުވަހަކީ މިއެވެ.","",""],["","","","يوم نطوي السماء كطي السجل للكتب كما بدأنا أول خلق نعيده وعدا علينا إنا كنا فاعلين","އެދުވަހަކީ، ފޮތްތަކުގެ ފަތްފުށް ފަތްޖަހައިލެވޭ ފަދައިން، ތިމަންރަސްކަލާނގެ އުޑު ފަތްޖައްސަވައިލައްވާ ދުވަހެވެ. އެންމެފުރަތަމަ އުފެއްދެވި ފަދައިން، އެ ތަކެތި އަލުން އިއާދަކުރައްވާ ހުށީމެވެ. އެއީ ތިމަންރަސްކަލާނގެ މައްޗަށްއޮތް ވައުދެކެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެކަންތައް ކުރައްވާހުށީމެވެ.","",""],["","","","ولقد كتبنا في الزبور من بعد الذكر أن الأرض يرثها عبادي الصالحون","ހަމަކަށަވަރުން، ތައުރާތުގެ ފަހުން ޒަބޫރުގައި ތިމަންރަސްކަލާނގެ ލިޔުއްވީމެވެ. ހަމަކަށަވަރުން، ބިން ވާރުތަވެ މިލްކުވާހުށީ، ތިމަންރަސްކަލާނގެ ސާލިހު އަޅުންނަށެވެ.","",""],["","","","إن في هذا لبلاغا لقوم عابدين","ހަމަކަށަވަރުން، އަޅުކަންކުރާ ބަޔަކަށް ފުދޭވަރުގެ އެންގުމެއް، މީގައިވާކަން ކަށަވަރެވެ.","",""],["","","","وما أرسلناك إلا رحمة للعالمين","އަދި އާލަމްތަކަށް ރަހުމަތެއްކަމުގައި މެނުވީ، ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނު ނުފޮނުއްވަމެވެ.","",""],["","","","قل إنما يوحى إلي أنما إلهكم إله واحد فهل أنتم مسلمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނަށް ވަހީ އިއްވަވާކަން ކަށަވަރީ، ތިޔަބައިމީހުންގެ އިލާހަކީ، އެއްކައުވަންތަ އިލާހެއް ކަމަށެވެ. ފަހެ، ތިޔަބައިމީހުންނީ (އެކަން ގަބޫލު ކޮށް) އިސްލާމްވާ ބަޔެއް ހެއްޔެވެ؟","",""],["","","","فإن تولوا فقل آذنتكم على سواء وإن أدري أقريب أم بعيد ما توعدون","ދެން އެއުރެން ފުރަގަސްދީފިނަމަ، ފަހެ، ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންނަށް ސާފުކޮށް (ހައްގު ގޮތް) އަންގަވައި ދެއްވައިފީމެވެ. އަދި ތިޔަބައިމީހުންނަށް ވައުދުކުރައްވާ ދުވަސްއޮތީ، ގާތުގައިކަން ނުވަތަ ދުރުގައިކަން ތިމަންކަލޭގެފާނަކަށް އެނގިވަޑައެއް ނުގަންނަވައެވެ.","",""],["","","","إنه يعلم الجهر من القول ويعلم ما تكتمون","ހަމަކަށަވަރުން، ފާޅުގައި ބުނެވޭބަސްތައް، އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަދި ތިޔަބައިމީހުން ވަންހަނާކުރާ ކަންތައްވެސް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","وإن أدري لعله فتنة لكم ومتاع إلى حين","(ތިޔަބައިމީހުން ލެހެއްޓެވިކަން) އެއީ، ތިޔަބައިމީހުންނަށްވާ އިމްތިހާނެއްކަން، ނުވަތަ ވަކި މުއްދަތަކާ ޖެހެންދެން ލިބޭވަގުތީ އުފަލެއްކަން، ތިމަންކަލޭގެފާނަކަށް އެނގިވަޑައެއް ނުގަންނަވަތެވެ.","",""],["","","","قال رب احكم بالحق وربنا الرحمن المستعان على ما تصفون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! (މި އަޅާއާއި، މުޝްރިކުންނާ ދެމެދު) ހައްގު ގޮތުގައި ހުކުމްކުރައްވާނދޭވެ! އަދި ތިޔަބައިމީހުން ސިފަކޮށް ބުނާއެއްޗެއްގެ މައްޗަށް (ކެތްކުރުމުގައި) އެހީދެއްވާފަރާތަކީ، އަޅަމެންގެ ވެރި، ރަޙްމާންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم يا أيها الناس اتقوا ربكم إن زلزلة الساعة شيء عظيم","އޭ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއަށް ތިޔަބައިމީހުން ތަގުވާވެރިވާށެވެ! ހަމަކަށަވަރުން، ގިޔާމަތް ވުމުގެ ޒަލްޒަލާއަކީ ބޮޑުވެގެންވާ ކަމެކެވެ.","",""],["","","","يوم ترونها تذهل كل مرضعة عما أرضعت وتضع كل ذات حمل حملها وترى الناس سكارى وما هم بسكارى ولكن عذاب الله شديد","ތިޔަބައިމީހުންނަށް އެ ޒަލްޒަލާ ފެންނަދުވަހު، ކިރުމައިން އެއުރެން ކިރުދޭ ދަރިންގެ މަތިން ހަނދާންނެތި، އަދި މާބަނޑުއަންހެނުން އެއުރެންގެ ބަނޑުގައިއޮތް ދަރި ވިހައި، އަދި މީސްތަކުން މަސްތުވެފައިވާފަދައިން ތިބާ ދެކޭނޫއެވެ. ނަމަވެސް އެއުރެންވަނީ، މަސްތުވެފައެއްނޫނެވެ. އެހެނެއްކަމަކު ﷲގެ އަޒާބު ގަދަފަދައީއެވެ.","",""],["","","","ومن الناس من يجادل في الله بغير علم ويتبع كل شيطان مريد","އެއްވެސް އިލްމަކާނުލައި، ﷲއާމެދު ޖަދަލުކޮށް، އަދި ނުކިޔަމަންތެރި ކޮންމެ ޝައިތާނަކަށް ތަބާ ވެއުޅޭމީހުން، މީސްތަކުންގެތެރެއިންވެއެވެ.","",""],["","","","كتب عليه أنه من تولاه فأنه يضله ويهديه إلى عذاب السعير","އެ ޝައިތާނާގެ މައްޗަށް ކަނޑައަޅުއްވައި ލިޔުއްވާފައިވަނީ، ހަމަކަށަވަރުން، އޭނާއަށް ތަބާވެ އެކުވެރިވެއްޖެމީހަކުނަމަ، ފަހެ، އެމީހަކު މަގުފުރައްދައި، ނަރަކައިގެ އަޒާބަށް މަގުދެއްކުމެވެ.","",""],["","","","يا أيها الناس إن كنتم في ريب من البعث فإنا خلقناكم من تراب ثم من نطفة ثم من علقة ثم من مضغة مخلقة وغير مخلقة لنبين لكم ونقر في الأرحام ما نشاء إلى أجل مسمى ثم نخرجكم طفلا ثم لتبلغوا أشدكم ومنكم من يتوفى ومنكم من يرد إلى أرذل العمر لكيلا يعلم من بعد علم شيئا وترى الأرض هامدة فإذا أنزلنا عليها الماء اهتزت وربت وأنبتت من كل زوج بهيج","އޭ މީސްތަކުންނޭވެ! (މަރުވުމަށްފަހު) އަލުން ދިރުއްވައި ފޮނުއްވާނޭ ކަމާމެދު، ތިޔަބައިމީހުން ޝައްކެއްގައިވާނަމަ، ފަހެ، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން (ގެ އަޞްލު) އުފެއްދެވީ، ވެލިންނެވެ. ދެން މަނިތިއްކަކުންނެވެ. ދެން ގަނޑުލޭކޮޅަކުންނެވެ. ދެން (އާދަމުގެދަރިޔެއްގެ) ސިފަ ފާޅުވެގެންވާ، ނުވަތަ ފާޅުވެގެންނުވާ މަސްކޮޅަކުންނެވެ. އެއީ (ކޮންމެކަމަކަށް ތިމަންރަސްކަލާނގެ ކުޅަދުންވަންތަކަން) ތިޔަބައިމީހުންނަށް ބަޔާންކޮށްދެއްވުމަށްޓަކައެވެ. އަދި ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާ އެއްޗެއް ކަނޑައަޅުއްވާފައިވާ މުއްދަތަކަށް ރަޙިމު ތަކުގައި ލަހައްޓަވަމެވެ. ދެން ޅަކުދިންގެ ގޮތުގައި ތިޔަބައިމީހުން (ދުނިޔެމައްޗަށް) ނެރުއްވަމެވެ. ދެން ތިޔަބައިމީހުން ބޮޑުވެ، ފުރާފުރިހަމަވުމާހަމަޔަށް ފޯރައެވެ. އަދި (ޒުވާންކަމުގެ ދުވަސްވަރު) މަރުވާމީހުން، ތިޔަބައިމީހުންގެ ތެރެއިންވެއެވެ. އަދި އަރްޛަލިލް އުމުރަށް ރައްދުކުރައްވާ މީހުން ތިޔަބައިމީހުންގެ ތެރެއިންވެއެވެ. އެއީ އޭނާޔަށް އެއްޗެއް އެނގުމަށްފަހުގައި، ނޭނގުމަށްޓަކައެވެ. އަދި ބިންގަނޑު މަރުވެފައިވަނިކޮށް ތިބާ ދެކޭނޫއެވެ. ފަހެ، އެ ބިމުގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ވާރޭ ވެއްސަވައިފިހިނދު، އެ ބިމުގެ ގަސްތަކުގެ ޙަރަކާތް ފެށި، ގަސްތައް އިތުރުވެއެވެ. އަދި ހުރިހާ ބާވަތަކުން، ބަލާމީހާޔަށް އުފާލިބެނިވި ގަސްތައް ފަޅުވަތެވެ.","",""],["","","","ذلك بأن الله هو الحق وأنه يحيي الموتى وأنه على كل شيء قدير","އެހެނީ ހަމަކަށަވަރުން، ﷲއީ، ހައްގުވަންތަ ރަސްކަލާނގެއެވެ. އަދި ހަމަކަށަވަރުން، އެކަލާނގެ މަރުވެފައިވާމީހުން ދިރުއްވަތެވެ. އަދި ހަމަކަށަވަރުން، އެކަލާނގެއީ، ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وأن الساعة آتية لا ريب فيها وأن الله يبعث من في القبور","އަދި ހަމަކަށަވަރުން، ގިޔާމަތް ވުމުގެ ވަގުތަކީ، އަންނާނޭ އެއްޗެކެވެ. އެއާމެދަކު ޝައްކެއްނެތެވެ. އަދި ހަމަކަށަވަރުން، ﷲ، ކަށްވަޅުތަކުގައި ތިބިމީހުން އަލުން ދިރުއްވައި ފޮނުއްވާހުށްޓެވެ.","",""],["","","","ومن الناس من يجادل في الله بغير علم ولا هدى ولا كتاب منير","އެއްވެސް އިލްމަކާނުލައި، އަދި އެއްވެސް ތެދުމަގެއް ލިބުމަކާނުލައި، އަދި އަލިކުރަނިވި ފޮތެއްވެސް ނެތި ﷲއާމެދު ޖަދަލުކުރާމީހުން، މީސްތަކުންގެތެރެއިންވެއެވެ.","",""],["","","","ثاني عطفه ليضل عن سبيل الله له في الدنيا خزي ونذيقه يوم القيامة عذاب الحريق","ﷲގެ މަގުން (މީސްތަކުން) އެއްކިބާކުރުމަށްޓަކައި (ބޮޑާކަމާއެކު) އޭނާގެ ކަނދުރާ އަނބުރައިލާ ޙާލު ގައެވެ. އެމީހަކަށް ދުނިޔެމަތީގައި ނިކަމެތިކަމާއި، ދެރަކަންހުށްޓެވެ. އަދި ގިޔާމަތް ދުވަހުން ނަރަކައިގެ އަޒާބުގެ ރަހަ، ތިމަންރަސްކަލާނގެ އެމީހަކަށް ދައްކަވާ ހުށީމެވެ.","",""],["","","","ذلك بما قدمت يداك وأن الله ليس بظلام للعبيد","އެއީ ތިބާގެ ދެއަތުން އިސްކުޅަ ކަންތަކުގެ ސަބަބުންނެވެ. އަދި ހަމަކަށަވަރުން، ﷲއީ، އަޅުތަކުންނަށް އަނިޔާވެރިވެވޮޑިގެންވާ ކަލަކުކަމުގައި ނުވެއެވެ.","",""],["","","","ومن الناس من يعبد الله على حرف فإن أصابه خير اطمأن به وإن أصابته فتنة انقلب على وجهه خسر الدنيا والآخرة ذلك هو الخسران المبين","ޝައްކެއްގެމަތީގައި ތިބެގެން، ﷲއަށް އަޅުކަންކުރާ މީހުން، މީސްތަކުންގެ ތެރެއިންވެއެވެ. ފަހެ، އެމީހަކަށް ހެޔޮކަމެއް ދިމާވެއްޖެނަމަ، އެކަމުން ހިތްހަމަޖެހެއެވެ. އަދި އޭނާޔަށް ބަލާއެއް މުސީބަތެއް ޖެހިއްޖެނަމަ، ކުފުރުވެރިކަމަށް ފުރޮޅިދެއެވެ. އޭނާޔަށް ދުނިޔެއާއި އާޚިރަތްގެއްލުނީއެވެ. ބަޔާންވެގެންވާ ގެއްލެނިވުމަކީ ހަމައެއީއެވެ.","",""],["","","","يدعو من دون الله ما لا يضره وما لا ينفعه ذلك هو الضلال البعيد","އެމީހަކަށް ގެއްލުމެއް ނުދޭ، އަދި މަންފާއެއްވެސް ނުދޭ އެއްޗަކަށް، ﷲ ފިޔަވައި އޭނާ އަޅުކަންކުރެތެވެ. (ހައްގުގެ މަގުން) ދުރުވެގެންވާ ފުރެދުމަކީ ހަމައެއީއެވެ.","",""],["","","","يدعو لمن ضره أقرب من نفعه لبئس المولى ولبئس العشير","އޭނާ އެ އަޅުކަންކުރަނީ، އެ އެއްޗެއްގެ މަންފާއަށްވުރެ، އެ އެއްޗެއްގެ ގެއްލުން މާގާތްވެގެންވާ އެއްޗަކަށެވެ. އޭނާ އެ ވާގިލިބިގަންނަ އެއްޗެއްގެ ނުބައިކަމާއެވެ! އަދި އެކުވެރިޔެއްގެ ގޮތުންވެސް އޭގެ ނުބައިކަމާއެވެ!","",""],["","","","إن الله يدخل الذين آمنوا وعملوا الصالحات جنات تجري من تحتها الأنهار إن الله يفعل ما يريد","ހަމަކަށަވަރުން، އީމާންވެ ސާލިހު ޢަމަލުތައްކުރި މީހުން، އެތަންތާނގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކަށް، ﷲ (އެއުރެން) ވައްދަވާނެތެވެ. ހަމަކަށަވަރުން، ﷲ، އެކަލާނގެ އިރާދަކުރައްވާކަމެއް ކުރައްވަތެވެ.","",""],["","","","من كان يظن أن لن ينصره الله في الدنيا والآخرة فليمدد بسبب إلى السماء ثم ليقطع فلينظر هل يذهبن كيده ما يغيظ","ދުނިޔެއާއި، އާޚިރަތުގައި އެކަލޭގެފާނަށް (އެބަހީ: ރަސޫލާއަށް) ﷲ ނަސްރު ނުދެއްވާނެކަމަށް ހީކުރާމީހާ، ފަހެ، މައްޗަށް ވަލެއްޖަހައި، ދެން އޭނާ ދަންޖެހިބަލާށެވެ! ފަހެ، އޭނާ ރޭވިރޭވުމުން، އޭނާ ރުޅިއަންނަކަންތައް ނިކަން ފިލައިތޯ ބަލައިބަލާށެވެ!","",""],["","","","وكذلك أنزلناه آيات بينات وأن الله يهدي من يريد","އެފަދައިން ބަޔާންވެގެންވާ އާޔަތް ތަކެއް ކަމުގައި، ތިމަންރަސްކަލާނގެ އެ ގުރްއާން ބާވައިލެއްވީމެވެ. އަދި ހަމަކަށަވަރުން، ﷲ، އެކަލާނގެ އިރަދާކުރައްވާ މީހަކަށް ތެދުމަގު ދައްކަވަތެވެ.","",""],["","","","إن الذين آمنوا والذين هادوا والصابئين والنصارى والمجوس والذين أشركوا إن الله يفصل بينهم يوم القيامة إن الله على كل شيء شهيد","ހަމަކަށަވަރުން، އީމާން ވިމީހުންނާއި، ޔަހޫދީވި މީހުންނާއި، ޞާބިއްނާއި، ނަސާރާ އިންނާއި، މަޖޫސީންނާއި، ޝަރީކުކުރި މީހުން (ދަންނާށެވެ!) ހަމަކަށަވަރުން، ﷲ، އެއުރެންގެމެދުގައި، ގިޔާމަތް ދުވަހުން ނިޔާކަނޑައަޅުއްވާނެތެވެ. ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެ ކަމެއްގެ މައްޗަށް، މޮޅަށް ހެކިވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ألم تر أن الله يسجد له من في السماوات ومن في الأرض والشمس والقمر والنجوم والجبال والشجر والدواب وكثير من الناس وكثير حق عليه العذاب ومن يهن الله فما له من مكرم إن الله يفعل ما يشاء","އުޑުތަކާއި، ބިމުގައިވާހާ ބަޔަކާއި، އިރާއި، ހަނދާއި، ތަރިތަކާއި، ފަރުބަދަތަކާއި، ގަސްގަހާގެއްސާއި، ޖަނަވާރުތަކާއި، މީސްތަކުންކުރެ ގިނަބަޔަކު، ﷲއަށް ސަޖިދަކުރާކަން ތިބާ ނުދަންނަމު ހެއްޔެވެ؟ އަދި (މީސްތަކުންކުރެ) ގިނަބަޔަކުގެމައްޗަށް އަޒާބު ހައްގު ވެގެންވެއެވެ. އަދި ﷲ، ނިކަމެތިކުރެއްވިމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް މާތްކޮށްހިތާނެ މީހަކު ނުވެތެވެ. ހަމަކަށަވަރުން، ﷲ، އެކަލާނގެ އިރާދަކުރައްވާކަމެއް ކުރައްވަތެވެ.","",""],["","","","هذان خصمان اختصموا في ربهم فالذين كفروا قطعت لهم ثياب من نار يصب من فوق رءوسهم الحميم","މިއީ، އެއުރެންގެ ވެރިރަސްކަލާނގެއާމެދު ދެބަސްވީ ދެ ޚަޞްމުންނެވެ. (އެބަހީ: މުއުމިންނާއި ކާފިރުންނެވެ.) ފަހެ، ކާފިރުވި މީހުންނަށް އަލިފާނުގެ ފޭރާންތަކެއް ތައްޔާރު ކުރައްވާފައިވެއެވެ. (އަދި) އެއުރެންގެ ބޯތަކުގެ މައްޗަށް ކެކިކެކިހުރި ހޫނުފެން އޮއްސަވާހުށްޓެވެ.","",""],["","","","يصهر به ما في بطونهم والجلود","އެއިން އެއުރެންގެ ބަނޑުތަކުގައިވާ ތަކެއްޗާއި ހަންތައް ވިރުވާހުށްޓެވެ.","",""],["","","","ولهم مقامع من حديد","އަދި އެއުރެންނަށްޓަކައި، ދަގަނޑު ޗާބޫކުތަކެއް ވެއެވެ.","",""],["","","","كلما أرادوا أن يخرجوا منها من غم أعيدوا فيها وذوقوا عذاب الحريق","އެއުރެންނަށް ލިބޭ ވޭނެއްގެ ގަދަކަމުން، އެތަނުން އެއުރެން ނުކުންނަން އުޅެފި ކޮންމެހިނދެއްގައި، އަލުން އެތަނަށް އިއާދަކުރައްވާ ހުށްޓެވެ. އަދި (އެއުރެންނަށް އަންގަވާނެތެވެ.) ނަރަކައިގެ އަލިފާނުގެ އަޒާބުގެ ރަހަ ތިޔަބައިމީހުން ލިބިގަންނާށެވެ!","",""],["","","","إن الله يدخل الذين آمنوا وعملوا الصالحات جنات تجري من تحتها الأنهار يحلون فيها من أساور من ذهب ولؤلؤا ولباسهم فيها حرير","ހަމަކަށަވަރުން، އީމާންވެ ސާލިހު ޢަމަލުތައްކުރިމީހުން، އެތަންތާނގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކަށް ﷲ (އެއުރެން) ވައްދަވާނެތެވެ. އެއުރެން އެތާނގައި ރަނުގެ އުޅާތަކުންނާއި، މުތީތަކުން ގަހަނާ އަޅުއްވާހުށްޓެވެ. އަދި އެތާނގައި، އެއުރެންގެ ފޭރާންވާހުށީ ފަށުއިންނެވެ.","",""],["","","","وهدوا إلى الطيب من القول وهدوا إلى صراط الحميد","އަދި (ދުނިޔެމަތީގައި) ރަނގަޅު ބަސްބުނުމަށް އެއުރެންނަށް ހިދާޔަތް ދެއްވިއެވެ. އަދި ހަމްދު ލިބިގެންވާ މަގަށް، މަގު ދެއްކެވިއެވެ.","",""],["","","","إن الذين كفروا ويصدون عن سبيل الله والمسجد الحرام الذي جعلناه للناس سواء العاكف فيه والباد ومن يرد فيه بإلحاد بظلم نذقه من عذاب أليم","ހަމަކަށަވަރުން، ކާފިރުވެ، ﷲގެ މަގުން (މީސްތަކުން) އެއްކިބާކޮށް، އަދި އެތާނގައި ގާއިމު ވެހުންނަ މީހާއާއި، ބޭރުން އަންނަމީހާއާއި، ހަމަހަމަވާގޮތުން، މީސްތަކުންނަށްޓަކައި، ތިމަންރަސްކަލާނގެ ލެއްވި އަލްމަސްޖިދުލް ހަރާމުން (މީސްތަކުން) އެއްކިބާކޮށް، އަދި އެތާނގައި އަނިޔާވެރިކަމާއެކު، ދީނާ ޚިލާފު ގޮތްތައް އުފައްދަންއުޅޭ މީހާއަށް، ތިމަންރަސްކަލާނގެ ވޭންދެނިވި އަޒާބުން ރަހަދައްކަވާހުށީމެވެ.","",""],["","","","وإذ بوأنا لإبراهيم مكان البيت أن لا تشرك بي شيئا وطهر بيتي للطائفين والقائمين والركع السجود","އިބްރާހީމްގެފާނަށް ގެފުޅު ހުންނަތަން ތިމަންރަސްކަލާނގެ ދެއްކެވިހިނދު، ހަނދުމަކުރާށެވެ! (ތިމަންރަސްކަލާނގެ އެންގެވީމެވެ.) ކަލޭގެފާނު ތިމަންރަސްކަލާނގެއަށް އެއްވެސް އެއްޗެއް ޝަރީކު ނުކުރައްވާށެވެ! އަދި ތަވާފުކުރާ މީހުންނަށާއި، ގާއިމު ވެތިބޭމީހުންނަށާއި، ރުކޫއު ކޮށް ސަޖިދަކުރާ މީހުންނަށްޓަކައި، ކަލޭގެފާނު ތިމަންރަސްކަލާނގެ ގެފުޅު ތާހިރުކުރައްވާށެވެ!","",""],["","","","وأذن في الناس بالحج يأتوك رجالا وعلى كل ضامر يأتين من كل فج عميق","އަދި ކަލޭގެފާނު މީސްތަކުންނަށް ހައްޖަށް އައުމަށް ގޮވައިލައްވާށެވެ! އޭރުން ފައިމަގުގައްޔާއި، އަނަރޫފަ ޖަމަލު މަތީގައި، ދުރުތަންތަނުން އެއުރެން ކަލޭގެފާނުގެ އަރިހަށް އަންނާނެތެވެ.","",""],["","","","ليشهدوا منافع لهم ويذكروا اسم الله في أيام معلومات على ما رزقهم من بهيمة الأنعام فكلوا منها وأطعموا البائس الفقير","އެއީ އެއުރެންނަށްހުރި (ދީނީ އަދި ދުނިޔަވީ) މަންފާތަކެއް ލިބިގަތުމަށްޓަކައެވެ. އަދި ކަނޑައެޅި އެނގިގެންވާ ދުވަސްތަކެއްގައި، އެއުރެން ﷲގެ އިސްމުފުޅު ހަނދުމަކޮށް އުޅުމަށެވެ. ނަޢަމް ސޫފީގެ ނިއުމަތެއުރެންނަށް ދެއްވިކަމަށްޓަކައެވެ. ފަހެ، ތިޔަބައިމީހުން އެއިން ކައިއުޅޭށެވެ! އަދި ދަތިޙާލު ގައިވާ ފަގީރުންނަށް (އެއިން) ކާންދޭށެވެ!","",""],["","","","ثم ليقضوا تفثهم وليوفوا نذورهم وليطوفوا بالبيت العتيق","ދެން އެއުރެންގައިވާ ކުނި މިލަތައް، އެއުރެން ފިލުވާހުށިކަމެވެ! އަދި އެއުރެންގެ ނަދުރުތައް ފުއްދާހުށިކަމެވެ! އަދި ޒަމާންވީ ގެފުޅުގައި އެއުރެން ތަވާފުކުރާހުށިކަމެވެ!","",""],["","","","ذلك ومن يعظم حرمات الله فهو خير له عند ربه وأحلت لكم الأنعام إلا ما يتلى عليكم فاجتنبوا الرجس من الأوثان واجتنبوا قول الزور","(ކަންހުރިމަގީ) އެއީއެވެ. އަދި ﷲގެ ހުރުމަތްތަކަށް މާތްކޮށްހިތާ މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށްޓަކައި އެކަންތައް އެމީހެއްގެ ވެރި ރަސްކަލާނގެ ހަޒުރަތުގައި ހެޔޮކަން ބޮޑެވެ. އަދި ތިޔަބައިމީހުންނަށް ނަޢަމް ސޫފި ހަލާލުކުރައްވާފައިވެއެވެ. (ގުރްއާންގައި ނަންގަނެވި) ތިޔަބައިމީހުންނަށް ކިޔައިދެއްވާ ތަކެތި މެނުވީއެވެ. ފަހެ (އަޅުކަންކުރެވޭ) ބުދުތަކުގެ ނުތާހިރުކަމުން ތިޔަބައިމީހުން ދުރުހެލިވާށެވެ! އަދި ދޮގު ހެކިބަސް ބުނުމުން ދުރުހެލިވާށެވެ!","",""],["","","","حنفاء لله غير مشركين به ومن يشرك بالله فكأنما خر من السماء فتخطفه الطير أو تهوي به الريح في مكان سحيق","ﷲއަށް އިހްލާސް ތެރިވެ، ބާތިލު މަގުން އެއްކިބާވެ، ހައްގުގެ މަގަށް ތަބާ ވެތިބެ، އެކަލާނގެއަށް ޝަރީކު ނުކުރާ ޙާލު ގައެވެ. އަދި ﷲއަށް ޝަރީކުކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާ އުޑުން ވެއްޓި، ދޫނިތައް އެމީހާ ޖަހައިގަނެގެން ގެންދާ ނުވަތަ ވައިގެ ބާރުން ދުރުތަނަކަށް ވެއްޓިގެންދާ މީހެއްފަދައެވެ.","",""],["","","","ذلك ومن يعظم شعائر الله فإنها من تقوى القلوب","(ކަންހުރިމަގީ) އެއީއެވެ. އަދި ﷲގެ ޝަޢާއިރުތަކަށް (އެބަހީ: ހަދުޔު ކަތިލުމާއި، އުޟުޙިޔާ ކަތިލުމާއި، ހައްޖުގެ ޢަމަލު ތަކާއި، އެނޫންވެސް ދީނީ އަމުރުތަކަށް) މާތްކޮށްހިތާމީހާ (ދަންނާށެވެ!) ފަހެ، އެކަންތައްވަނީ، ހިތްތަކުގެ ތަގުވާވެރިކަމުގެ ތެރެއިންނެވެ.","",""],["","","","لكم فيها منافع إلى أجل مسمى ثم محلها إلى البيت العتيق","ކަނޑައެޅިގެންވާ ވަގުތަކާޖެހެންދެން، ތިޔަބައިމީހުންނަށް އެތަކެތީގައި (އެބަހީ: ހަދުޔުގެ ގޮތުން ކަތިލެވޭ ތަކެތީގައި) މަންފާތަކެއްވެއެވެ. ދެން އެއަށްފަހު، އެތަކެތި ކަތިލުމުގެ މަޙައްލަކީ، ޒަމާންވީ ގެފުޅުއަރިހެވެ. (އެބަހީ: މައްކާގެ ހަރަމް ފުޅެވެ.)","",""],["","","","ولكل أمة جعلنا منسكا ليذكروا اسم الله على ما رزقهم من بهيمة الأنعام فإلهكم إله واحد فله أسلموا وبشر المخبتين","ނަޢަމް ސޫފީގެތެރެއިން އެކަލާނގެ އެއުރެންނަށް ދެއްވި ތަކެތީގެ މައްޗަށް (އެބަހީ: އެތަކެތި ކަތިލެވޭހިނދު) ﷲގެ އިސްމުފުޅު ނަންގަތުމަށްޓަކައި، ތިމަންރަސްކަލާނގެ ކޮންމެ އުއްމަތަކަށްވެސް ގުރުބާންކުރުމެއް ލެއްވީމެވެ. ފަހެ، ތިޔަބައިމީހުންގެ ކަލާނގެއީ، އެއްކައުވަންތަކަލާނގެއެވެ. ފަހެ، އެކަލާނގެއަށް ތިޔަބައިމީހުން ކިޔަމަންވެ، އިސްލާމް ވާށެވެ! އަދި ކިޔަމަންތެރިންނަށް ކަލޭގެފާނު އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާށެވެ!","",""],["","","","الذين إذا ذكر الله وجلت قلوبهم والصابرين على ما أصابهم والمقيمي الصلاة ومما رزقناهم ينفقون","އެއުރެންނީ، ﷲގެ ނަންފުޅު ގަނެވޭހިނދު، އެއުރެންގެ ހިތްތައް ބިރުވެތިވެ މަޑުމޮޅިވާ މީހުންނެވެ. އަދި އެއުރެންނަށްޖެހޭ ކަންތަކަށް ކެތްތެރިވާމީހުންނެވެ. އަދި ނަމާދު ގާއިމު ކޮށް ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްވި ތަކެތިން ހޭދަކުރާ މީހުންނެވެ.","",""],["","","","والبدن جعلناها لكم من شعائر الله لكم فيها خير فاذكروا اسم الله عليها صواف فإذا وجبت جنوبها فكلوا منها وأطعموا القانع والمعتر كذلك سخرناها لكم لعلكم تشكرون","ތިޔަބައިމީހުންނަށްޓަކައި، ޖަމަލުވެސް ﷲގެ ޝަޢާއިރުތަކުގެ ތެރެއިން ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ. އޭގައި ތިޔަބައިމީހުންނަށް ހެޔޮކަމެއްވެއެވެ. ފަހެ، އެތަކެތި ބަނދެ (ކަތިލާހިނދުގައި) އެ ތަކެތީގެ މައްޗަށް ﷲގެ އިސްމުފުޅު ތިޔަބައިމީހުން ކިޔާށެވެ! ފަހެ، އެތަކެތި (މަރުވެ) ވެއްޓުމުން އެއިން ތިޔަބައިމީހުން ކާށެވެ! އަދި އެއަށްއެދި ސުވާލުކުރާ ފަގީރްނާއި، ސުވާލު ނުކުރާ ފަގީރުންނަށްވެސް އެއިން ކާންދޭށެވެ! އެފަދައިން ތިޔަބައިމީހުންނަށްޓަކައި ތިމަންރަސްކަލާނގެ އެތަކެތި ޚިދުމަތް ތެރިކުރެއްވީމެވެ. (އެއީ) ތިޔަބައިމީހުން ޝުކުރުކުރުމަށްޓަކައެވެ.","",""],["","","","لن ينال الله لحومها ولا دماؤها ولكن يناله التقوى منكم كذلك سخرها لكم لتكبروا الله على ما هداكم وبشر المحسنين","އެތަކެތީގެ މަހެއްވެސް އަދި ލެޔެއްވެސް ﷲގެ ހަޒުރަތަކަށް ނުދާނެތެވެ. އެހެނެއްކަމަކު، ތިޔަބައިމީހުންގެކިބައިން އެކަލާނގެ ހަޒުރަތަށްދަނީ، ތަގުވާވެރިކަމެވެ. އެފަދައިން އެކަލާނގެ އެތަކެތި، ތިޔަބައިމީހުންނަށްޓަކައި ޚިދުމަތް ތެރިކުރެއްވިއެވެ. (އެއީ) ތިޔަބައިމީހުންނަށް ތެދުމަގު ދެއްކެވިކަމުގެމައްޗަށް، ﷲއަށް ތިޔަބައިމީހުން ތަކްބީރު ކިޔައި އުޅުމަށްޓަކައެވެ. އަދި އިހްސާން ތެރިންނަށް ކަލޭގެފާނު އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާށެވެ!","",""],["","","","إن الله يدافع عن الذين آمنوا إن الله لا يحب كل خوان كفور","ހަމަކަށަވަރުން، ﷲ، އީމާންވި މީހުން ދިފާޢު ކޮށްދެއްވަތެވެ. ހަމަކަށަވަރުން، ޚިޔާނަތް ތެރިވެ، ކާފިރުވާ ކޮންމެ މީހަކަށް، ﷲ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["","","","أذن للذين يقاتلون بأنهم ظلموا وإن الله على نصرهم لقدير","ހަނގުރާމަވެވެމުންދާ މީހުންނަށް، ހަނގުރާމަ ކުރުމުގެ އިޒުނަ ދެއްވައިފިއެވެ. އެއީ ހަމަކަށަވަރުން، އެއެރުންނަށް އަނިޔާ ލިބުނުކަމަށްޓަކައެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެންނަށް ނަސްރު ދެއްވުމަށް، ﷲކުޅަދުންވަންތަކަން ކަށަވަރެވެ.","",""],["","","","الذين أخرجوا من ديارهم بغير حق إلا أن يقولوا ربنا الله ولولا دفع الله الناس بعضهم ببعض لهدمت صوامع وبيع وصلوات ومساجد يذكر فيها اسم الله كثيرا ولينصرن الله من ينصره إن الله لقوي عزيز","އެއުރެންނީ، ތިމަންމެންގެ ވެރިރަސްކަލާނގެއީ، ﷲ އޭ ބުނުން މެނުވީ، އެއްވެސް ހައްގަކާނުލައި އެއުރެންގެ ގޯތިގެދޮރުން ނެރެލެވުނުމީހުންނެވެ. އަދި މީސްތަކުންކުރެ އެއްބަޔަކު މެދުވެރިކުރައްވައި އަނެއްބަޔަކު (ގެ ނުރައްކާތެރިކަން) ﷲ ދުރުކުރެއްވުން ނުވާނަމަ، ނަސާރާ އިންގެ ފައްޅިތަކާއި، އަޅުކަންކުރާ ތަންތަނާއި، ޔަހޫދީންގެ ފައްޅިތަކާއި، ގިނަގިނައިން ﷲގެ އިސްމުފުޅު ނަންގަނެވޭ މިސްކިތްތަކާއި (މިހުރިހާ ތަންތަން) ސުންނާފަތިކޮށްފީސްކަން ކަށަވަރެވެ. ހަމަކަށަވަރުން، ﷲއަށް ނަސްރު ދޭ މީހަކަށް، އެކަލާނގެ ނަސްރު ދެއްވާނެކަން ކަށަވަރެވެ. ހަމަކަށަވަރުން، ﷲއީ، ބާރުވެރިވަންތަ، ޢަޒީޒުވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","الذين إن مكناهم في الأرض أقاموا الصلاة وآتوا الزكاة وأمروا بالمعروف ونهوا عن المنكر ولله عاقبة الأمور","އެއުރެންނީ، ބިމުގައި ތިމަންރަސްކަލާނގެ އެއުރެން ބާރުވެރިކުރައްވައިފިނަމަ، ނަމާދު ގާއިމު ކޮށް، ޒަކާތް ދީ، ހެޔޮކަންތަކަށް އަމުރު ކޮށް، ނުބައިކަންތައް ނަހީކޮށްއުޅޭ މީހުންނެވެ. ކަންކަމުގެ ނިމުންވަނީ ﷲއަށެވެ.","",""],["","","","وإن يكذبوك فقد كذبت قبلهم قوم نوح وعاد وثمود","އެއުރެން ކަލޭގެފާނު ދޮގުކުޅަޔަސް، ހަމަކަށަވަރުން، އެއުރެންގެކުރިން ނޫޙުގެފާނުގެ ގައުމުގެމީހުންނާއި، ޢާދު ބާގައިމީހުންނާއި، ޘަމޫދު ބާގައިމީހުން (އެއުރެންގެ ރަސޫލުން) ދޮގުކޮށްފައިވެއެވެ.","",""],["","","","وقوم إبراهيم وقوم لوط","އަދި އިބްރާހީމްގެފާނުގެ ގައުމުގެމީހުންނާއި، ލޫޠުގެފާނުގެ ގައުމުގެމީހުންވެސްމެއެވެ.","",""],["","","","وأصحاب مدين وكذب موسى فأمليت للكافرين ثم أخذتهم فكيف كان نكير","އަދި މަދްޔަންގެ އަހުލުވެރިންވެސްމެއެވެ. އަދި މޫސާގެފާނުވެސް ދޮގުކުރެވުނެވެ. ފަހެ، ކާފިރުވި މީހުންނަށް، ތިމަންރަސްކަލާނގެ މުހުލަތް ދެއްވީމެވެ. ދެން ތިމަންރަސްކަލާނގެ އެއުރެންނަށް އުގޫބާތް ދެއްވައި ހިއްޕެވީމެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ އުގޫބާތް ދެއްވުންވީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","فكأين من قرية أهلكناها وهي ظالمة فهي خاوية على عروشها وبئر معطلة وقصر مشيد","އެރަށްތަކުގެ އަހުލުވެރިން، އަނިޔާވެރިވެގެންވީހިނދު، ތިމަންރަސްކަލާނގެ ހަލާކުކުރެއްވީ ކިތައްކިތައްރަށް ހެއްޔެވެ؟ ފަހެ، އެ ރަށްރަށްވަނީ، ފުރާޅުތަކާއި، އިމާރާތްތައް ވެއްޓި ފުނޑުފުނޑުވެފައެވެ. އަދި (އެ ރަށްރަށުގައިވަނީ) ފަޅުވެފައިވާ ކިތައްކިތައް ވަޅާއި، އުސްކޮށް ބިނާކޮށްފައިވާ ކިތައްކިތައް ގަނޑުވަރު ހެއްޔެވެ؟","",""],["","","","أفلم يسيروا في الأرض فتكون لهم قلوب يعقلون بها أو آذان يسمعون بها فإنها لا تعمى الأبصار ولكن تعمى القلوب التي في الصدور","ފަހެ، އެއުރެން ބިމުގައި ދަތުރުފަތުރުކޮށް ނޫޅެނީހެއްޔެވެ؟ އެހެންނަމަ، އެއުރެން އެއިން ވިސްނައިހަދާނޭ ހިތްތަކެއް އެއުރެންނަށްވީހެވެ. ނުވަތަ އެއިން އެއުރެން އަޑުއަހާނޭ ކަންފަތްތަކެއް (އެއުރެންނަށް) ވީހެވެ. އެހެނީ ހަމަކަށަވަރުން، ލޯތައް ކަނުވަނީއަކީނޫނެވެ. އެހެނެއްކަމަކު، ކަނުވަނީ މޭތަކުގައިވާ ހިތްތަކެވެ.","",""],["","","","ويستعجلونك بالعذاب ولن يخلف الله وعده وإن يوما عند ربك كألف سنة مما تعدون","އެއުރެން ކަލޭގެފާނުގެ އަރިހުން އަޒާބު އަވަސްވުމަށް އެދޭނެތެވެ. އަދި ﷲ، އެކަލާނގެ ވައުދު ފުޅަކާ ޚިލާފު ވެވޮޑިއެއް ނުގަންނަވާނެތެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި، އެންމެ ދުވަހެއްވަނީ، ތިޔަބައިމީހުން ގުނައި އަދަދުކުރާ އަހަރުތަކުން އެއްހާސް އަހަރާ އެއްފަދަވެގެންނެވެ.","",""],["","","","وكأين من قرية أمليت لها وهي ظالمة ثم أخذتها وإلي المصير","އެ ރަށްތަކުގެ އަހުލުވެރިން އަނިޔާވެރިވެގެންވީ ހިނދު، ތިމަންރަސްކަލާނގެ މުހުލަތް ދެއްވީ ކިތައްކިތައް ރަށަށް ހެއްޔެވެ؟ ދެން އެ ރަށްތަކުގެ އަހުލުވެރިންނަށް އުގޫބާތް ދެއްވައި ހިއްޕެވީމެވެ. އަދި (އެއުރެން) ރުޖޫއަ ވުންވަނީ، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","قل يا أيها الناس إنما أنا لكم نذير مبين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ މީސްތަކުންނޭވެ! ތިމަންކަލޭގެފާނު ވާކަން ކަށަވަރީ، ތިޔަބައިމީހުންނަށްޓަކައި ހުންނެވި އިންޒާރުކުރައްވާ ބޭކަލަކު ކަމުގައެވެ.","",""],["","","","فالذين آمنوا وعملوا الصالحات لهم مغفرة ورزق كريم","ފަހެ، އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަމީހުން (ދަންނާށެވެ!) އެއުރެންނަށް ފާފުފުއްސެވުމާއި، ދީލަތިވެގެންވާ ރިޒްގު ހުށްޓެވެ.","",""],["","","","والذين سعوا في آياتنا معاجزين أولئك أصحاب الجحيم","އަދި ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާމެދު، ދެކޮޅުހަދައި ނުކުޅައްދަން އުޅޭމީހުންނަކީ، ނަރަކައިގެ އަހުލުވެރިންނެވެ.","",""],["","","","وما أرسلنا من قبلك من رسول ولا نبي إلا إذا تمنى ألقى الشيطان في أمنيته فينسخ الله ما يلقي الشيطان ثم يحكم الله آياته والله عليم حكيم","އެބޭކަލަކު ކިޔަވައިވިދާޅުވެއްޖެހިނދު، އެބޭކަލެއްގެ ކިޔަވައި ވިދާޅުވުމުގެ ތެރެޔަށް، ޝައިތާނާ، އޭނާގެ ވަސްވާސްތެރިކަން ވައްދާފައިވާ ބޭކަލަކު މެނުވީ، ކަލޭގެފާނުގެކުރިން އެއްވެސް ރަސޫލަކު، އަދި ނަބިއްޔަކުވެސް، ތިމަންރަސްކަލާނގެ ނުފޮނުއްވަމެވެ. ފަހެ، ﷲ، ޝައިތާނާ ވައްދާ ވަސްވާސްތެރިކަން ނެތިކުރައްވަތެވެ. ދެން ﷲ، އެކަލާނގެ އާޔަތްތައް ޘާބިތު ކޮށްދެއްވަތެވެ. ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ليجعل ما يلقي الشيطان فتنة للذين في قلوبهم مرض والقاسية قلوبهم وإن الظالمين لفي شقاق بعيد","އެއީ އެއުރެންގެ ހިތްތަކުގައި ބަލިމަޑުކަމެއް ހުންނަ މީހުންނަށާއި، އެއުރެންގެ ހިތްތައް ހަރުކަށިވެފައިވާ މީހުންނަށް، އިމްތިހާނެއްކަމުގައި، ޝައިތާނާ ވައްދާ ވަސްވާސްތެރިކަން ލެއްވުމަށްޓަކައެވެ. ހަމަކަށަވަރުން، އަނިޔާވެރިންވަނީ (ހައްގާ) ދުރުވެގެންވާ ދެކޮޅުވެރިކަމެއްގެ ތެރޭގައެވެ.","",""],["","","","وليعلم الذين أوتوا العلم أنه الحق من ربك فيؤمنوا به فتخبت له قلوبهم وإن الله لهاد الذين آمنوا إلى صراط مستقيم","އަދި އިލްމު ލިބިގެންވާ މީހުންނަށް، ހަމަކަށަވަރުން، އެއީ ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައި ހައްގު ބަސްފުޅުކަން އެނގުމަށްޓަކައެވެ. ދެން އެއަށް އީމާންވެ، ދެން އެއާމެދު އެއުރެންގެ ހިތްތައް ހަމަޖެހިގެންދިއުމަށްޓަކައެވެ. ހަމަކަށަވަރުން، ﷲއީ، އީމާންވި މީހުންނަށް ސީދާވެގެންވާ ތެދުމަގަށް މަގުދައްކަވާ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","ولا يزال الذين كفروا في مرية منه حتى تأتيهم الساعة بغتة أو يأتيهم عذاب يوم عقيم","ކާފިރު ވިމީހުން، އެ ގުރްއާނާމެދު ޝައްކުކަމެއްގައި ތިބުމުން ފިލައިނުދެތެވެ. ގިޔާމަތް ވުމުގެ ވަގުތު ކުއްލިއަކަށް އެއުރެންނާހަމަޔަށް އަތުވެއްޖައުމަށް ދާނދެނެވެ. ނުވަތަ ރޭގަނޑެއް ނެތް ދުވަހެއްގެ (އެބަހީ: ގިޔާމަތް ދުވަހުގެ) އަޒާބު، އެއުރެންނާހަމަޔަށް އަތުވެއްޖައުމަށް ދާނދެނެވެ.","",""],["","","","الملك يومئذ لله يحكم بينهم فالذين آمنوا وعملوا الصالحات في جنات النعيم","އެދުވަހުން، ވެރިކަން މިލްކުވެގެންވަނީ ﷲއަށެވެ. އެއުރެންގެ މެދުގައި އެކަލާނގެ ހުކުމްކުރައްވާނެތެވެ. ފަހެ، އީމާންވެ ސާލިހު ޢަމަލުތައްކުޅަމީހުން ވާހުށީ، ނިއުމަތްގެ ސުވަރުގެތަކުގައެވެ.","",""],["","","","والذين كفروا وكذبوا بآياتنا فأولئك لهم عذاب مهين","އަދި ކާފިރުވެ، ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުޅަ މީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެންނަށް އިހާނަތް ތެރިކަން ދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["","","","والذين هاجروا في سبيل الله ثم قتلوا أو ماتوا ليرزقنهم الله رزقا حسنا وإن الله لهو خير الرازقين","އަދި ﷲގެ މަގުގައި ހިޖުރަ ކޮށް، ދެން (ހަނގުރާމަކޮށް) ގަތުލު ވީ މީހުންނަށް، ނުވަތަ މަރުވި މީހުންނަށް، ހަމަކަށަވަރުން، ﷲ، އެއުރެންނަށް ރަނގަޅު ރިޒްގުން ރިޒްގު ދެއްވާނެތެވެ. ހަމަކަށަވަރުން، ﷲއީ، ރިޒްގު ދެއްވާ އެންމެހެޔޮ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","ليدخلنهم مدخلا يرضونه وإن الله لعليم حليم","ހަމަކަށަވަރުން، އެއުރެން ރުހޭތަނަކަށް (އެބަހީ: ސުވަރުގެއަށް) އެކަލާނގެ، އެއުރެން ވައްދަވާހުށްޓެވެ. ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ހަލީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","ذلك ومن عاقب بمثل ما عوقب به ثم بغي عليه لينصرنه الله إن الله لعفو غفور","(ކަންހުރިމަގީ) އެއީއެވެ. އަދި އެމީހަކަށް ލިބުނު އަނިޔާއާ އެއްފަދަ ޖަޒާއެއް ދީފިމީހާ، ދެން އޭނާގެމައްޗަށް އަނިޔާ އިތުރަށް ދީފިނަމަ، ހަމަކަށަވަރުން، ﷲ، އޭނާޔަށް ނަސްރު ދެއްވާހުށްޓެވެ. ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން އަފޫކުރައްވާ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","ذلك بأن الله يولج الليل في النهار ويولج النهار في الليل وأن الله سميع بصير","އެހެނީ، ހަމަކަށަވަރުން، ﷲ، ދުވާލުގެތެރެޔަށް ރޭގަނޑު ވައްދަވަތެވެ. އަދި ރޭގަނޑުގެ ތެރެޔަށް ދުވާލު ވައްދަވަތެވެ. އަދި ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ބައްލަވާވޮޑިގެންވާ، ރަސްކަލާނގެއެވެ.","",""],["","","","ذلك بأن الله هو الحق وأن ما يدعون من دونه هو الباطل وأن الله هو العلي الكبير","އެހެނީ، ހަމަކަށަވަރުން، ﷲއީ، ހައްގުވަންތަ ރަސްކަލާނގެއެވެ. އަދި ހަމަކަށަވަރުން، އެކަލާނގެ ފިޔަވައި، އެއުރެން އަޅުކަންކުރާ ތަކެއްޗަކީ، އެއީ ބާތިލު ތަކެއްޗެވެ. އަދި ހަމަކަށަވަރުން، ﷲއީ، އެންމެމަތިވެރި، އެންމެޢަޡަމަތް ތެރި ރަސްކަލާނގެއެވެ.","",""],["","","","ألم تر أن الله أنزل من السماء ماء فتصبح الأرض مخضرة إن الله لطيف خبير","ހަމަކަށަވަރުން، ﷲ، އުޑުން ފެންވެއްސަވައި، ދެން (ގަސްގަހާގެހިން) ބިންގަނޑަށް ފެހިކަންލިބޭތީ ތިބާ ނުދެކެމުހެއްޔެވެ؟ ހަމަކަށަވަރުން، ﷲއީ، އޯގާވަންތަކަންބޮޑު، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","له ما في السماوات وما في الأرض وإن الله لهو الغني الحميد","އުޑުތަކުގައިވާހާ ތަކެއްޗާއި، ބިމުގައިވާހާތަކެތި މިލްކުވެގެންވަނީ، އެކަލާނގެއަށެވެ. އަދި ހަމަކަށަވަރުން، ﷲއީ، ފުދިވޮޑިގެންވާ، ގިނަގިނައިން ހަމްދު ލިބިވޮޑިގެންވާ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","ألم تر أن الله سخر لكم ما في الأرض والفلك تجري في البحر بأمره ويمسك السماء أن تقع على الأرض إلا بإذنه إن الله بالناس لرءوف رحيم","ހަމަކަށަވަރުން، ﷲ، ބިމުގައިވާހާތަކެއްޗެއް ތިޔަބައިމީހުންނަށްޓަކައި ޚިދުމަތް ތެރިކުރެއްވިކަމާއި، ކަނޑުގައި ނާފަހަރު ދުވަނީ، އެކަލާނގެ އަމުރު ފުޅާ އެކުގައިކަމާއި، އެކަލާނގެ އިޒުނަ ފުޅާލައިގެން މެނުވީ، ބިމުގެ މައްޗަށް އުޑު ނުވެއްޓޭގޮތުން ހިފަހައްޓަވާކަން، ތިބާއަށް ނޭނގެނީ ހެއްޔެވެ؟ ހަމަކަށަވަރުން، ﷲއީ، މީސްތަކުންނަށް ނުހަނު އޯގާވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","وهو الذي أحياكم ثم يميتكم ثم يحييكم إن الإنسان لكفور","އެކަލާނގެއީ، ތިޔަބައިމީހުން (ނެތުމުގެތެރެއިން) ދިރުއްވައި، ދެން ތިޔަބައިމީހުން މަރުގަންނަވައި، ދެން ތިޔަބައިމީހުން (އަލުން) ދިރުއްވާ ރަސްކަލާނގެއެވެ. ހަމަކަށަވަރުން، އިންސާނާއަކީ (ނިއުމަތްތަކަށް) ދެކޮޅުހަދައި، ކާފިރު ވުން ބޮޑު މީހެއްކަން ކަށަވަރެވެ.","",""],["","","","لكل أمة جعلنا منسكا هم ناسكوه فلا ينازعنك في الأمر وادع إلى ربك إنك لعلى هدى مستقيم","ތިމަންރަސްކަލާނގެ ކޮންމެ އުއްމަތަކަށްވެސް ޝަރީޢަތެއް، އެއުރެން އެއަށް ތަބާ ވުމަށްޓަކައި ލެއްވީމެވެ. ފަހެ، އެއުރެން އެކަންތަކާމެދު ކަލޭގެފާނާ ޖަދަލު ނުކުރާހުށިކަމެވެ! އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެމަގަށް (މީސްތަކުންނަށް) ކަލޭގެފާނު ގޮވައިލައްވާށެވެ! ހަމަކަށަވަރުން، ކަލޭގެފާނުވަނީ، ސީދާވެގެންވާ ހިދާޔަތެއްގެ މަތީގައިކަން ކަށަވަރެވެ.","",""],["","","","وإن جادلوك فقل الله أعلم بما تعملون","އަދި އެއުރެން ކަލޭގެފާނާ ޖަދަލު ކޮށްފިނަމަ، ފަހެ، ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންކުރާ ކަންތައް ﷲ ދެނެވޮޑިގަތުން ބޮޑެވެ.","",""],["","","","الله يحكم بينكم يوم القيامة فيما كنتم فيه تختلفون","ތިޔަބައިމީހުން ޚިލާފު ވެއުޅުނު ކަންތަކާމެދު، ގިޔާމަތް ދުވަހުން، ﷲ ތިޔަބައިމީހުންގެ މެދުގައި ހުކުމްކުރައްވާނެތެވެ.","",""],["","","","ألم تعلم أن الله يعلم ما في السماء والأرض إن ذلك في كتاب إن ذلك على الله يسير","ހަމަކަށަވަރުން، އުޑާއި، ބިމުގައިވާހާކަމެއް، ﷲ ދެނެވޮޑިގެންވާކަން ތިބާޔަށް ނޭނގެނީހެއްޔެވެ؟ ހަމަކަށަވަރުން، އެކަންތައްވަނީ، ފޮތެއްގައި ލިޔުއްވައިފައެވެ. ހަމަކަށަވަރުން، އެކަންތަކަކީ، ﷲއަށް ދާދިފަސޭހަކަމެކެވެ.","",""],["","","","ويعبدون من دون الله ما لم ينزل به سلطانا وما ليس لهم به علم وما للظالمين من نصير","(އެތަކެއްޗަށް އަޅުކަންކުރުމަށް) އެއްވެސް ދަލީލެއް އެކަލާނގެ ބާވައިލައްވާފައިނުވާ ތަކެއްޗަށް، ﷲ ފިޔަވައި އެއުރެން އަޅުކަން ކުރެތެވެ. އަދި އެއުރެންނަކަށް އެކަމާމެދު އެއްވެސް އިލްމެއް ލިބިގެނެއް ނުވެތެވެ. އަދި އަނިޔާވެރިންނަށް، ނަސްރު ދޭނެ އެއްވެސްމީހަކު ނުވެތެވެ.","",""],["","","","وإذا تتلى عليهم آياتنا بينات تعرف في وجوه الذين كفروا المنكر يكادون يسطون بالذين يتلون عليهم آياتنا قل أفأنبئكم بشر من ذلكم النار وعدها الله الذين كفروا وبئس المصير","އަދި އެއުރެންނަށް ތިމަންރަސްކަލާނގެ އާޔަތްތައް ބަޔާންވެގެންވާ ގޮތުގައި ކިޔައިދެއްވާހިނދު، ކާފިރުވި މީހުންގެ މޫނުމަތިން ދެކޮޅުވެރިކަމާއި، ނުރުހުމުގެ އަލާމަތްތައް ތިބާޔަށް ފެންނާނެތެވެ. ތިމަންރަސްކަލާނގެ އާޔަތްތައް އެއުރެންނަށް ކިޔަވައިދޭ މީހުންގެ ގަޔަށް ދެންމެދެންމެ އެއުރެން އަރައިދާނެކަހަލައެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ފަހެ، އެކަންތަކަށްވުރެ ބޮޑު ނުބަޔަކާ ތިޔަބައިމީހުން ކުރިމަތިވާނެކަމަށް، ތިމަންކަލޭގެފާނު ތިޔަބައިމީހުންނަށް ޚަބަރު ދެއްވަން ހެއްޔެވެ؟ އެއީ ނަރަކައެވެ. ކާފިރުވި މީހުންނަށް ﷲ ވަނީ، އެ ނަރަކަ ވައުދުކުރައްވައިފައެވެ. އަދި އެއީ ހާދަހާ ނުބައިވެގެންވާ ނިމިދިއުމެކެވެ.","",""],["","","","يا أيها الناس ضرب مثل فاستمعوا له إن الذين تدعون من دون الله لن يخلقوا ذبابا ولو اجتمعوا له وإن يسلبهم الذباب شيئا لا يستنقذوه منه ضعف الطالب والمطلوب","އޭ މީސްތަކުންނޭވެ! (ﷲ) މިސާލެއް ޖައްސަވައިފިއެވެ. ފަހެ، ތިޔަބައިމީހުން އެއަށް ކަނުލައި އަހާށެވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ﷲ ފިޔަވައި އަޅުކަންކުރާ ތަކެއްޗަކަށް މެއްސެއްވެސް ނެހެދޭނެތެވެ. އެކަމަށް އެ އެންމެން އެއްވިނަމަވެސްމެއެވެ. އަދި އެ މެހި، އެއުރެންގެ ކިބައިން އެއްޗެއް އަތުލައިފިނަމަ، އެވެސް އެ މެހީގެ ކިބައިން، އެއުރެންނަކަށް ސަލާމަތެއް ނުކުރެވޭނެތެވެ. އެދޭ މީހާއާއި އެދެވޭ ފަރާތްވެސް ނިކަމެތިވެގެންވެތެވެ.","",""],["","","","ما قدروا الله حق قدره إن الله لقوي عزيز","ﷲއަށް ގަދަރުކުރުން ހައްގު ވެގެންވާ ގޮތުގައި، އެއުރެން އެކަލާނގެއަށް ގަދަރެއް ނުކުރެތެވެ. ހަމަކަށަވަރުން، ﷲއީ، ބާރުވެރިވަންތަ، ޢަޒީޒުވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","الله يصطفي من الملائكة رسلا ومن الناس إن الله سميع بصير","ﷲ، މަލާއިކަތުންގެ ތެރެއިންނާއި މީސްތަކުންގެތެރެއިން ރަސޫލުން ޚިޔާރުކުރައްވަތެވެ. ހަމަކަށަވަރުން، ﷲއީ މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","يعلم ما بين أيديهم وما خلفهم وإلى الله ترجع الأمور","އެއުރެންގެ ކުރިމަތީގައި ވާހާކަމަކާއި އެއުރެންގެ ފަހަތުގައި ވާހާކަމެއް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަދި އެންމެހާ ކަންތައް ރުޖޫއަކުރައްވާހުށީ ﷲގެ ހަޒުރަތަށެވެ.","",""],["","","","يا أيها الذين آمنوا اركعوا واسجدوا واعبدوا ربكم وافعلوا الخير لعلكم تفلحون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ރުކޫއު ކޮށް، ސަޖިދަކުރާށެވެ! އަދި ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއަށް އަޅުކަން ކުރާށެވެ! އަދި ތިޔަބައިމީހުން ހެޔޮކަންތައްކުރާށެވެ! (އެއީ) ތިޔަބައިމީހުން ދިންނަވައި، ނަސީބު ލިބުމަށްޓަކައެވެ.","",""],["","","","وجاهدوا في الله حق جهاده هو اجتباكم وما جعل عليكم في الدين من حرج ملة أبيكم إبراهيم هو سماكم المسلمين من قبل وفي هذا ليكون الرسول شهيدا عليكم وتكونوا شهداء على الناس فأقيموا الصلاة وآتوا الزكاة واعتصموا بالله هو مولاكم فنعم المولى ونعم النصير","އަދި ﷲގެ މަގުގައި ޖިހާދުކުރުން ހައްގު ވެގެންވާ ގޮތުގައި ތިޔަބައިމީހުން ޖިހާދުކުރާށެވެ! (އުއްމަތް ތަކުގެތެރެއިން) އެކަލާނގެ ތިޔަބައިމީހުން ޚިޔާރުކުރެއްވިއެވެ. އަދި ދީންގައި އުނދަގޫވެގެންވާ ދަތިކަމެއް އެކަލާނގެ ތިޔަބައިމީހުންގެ މައްޗަކަށް ނުލައްވަތެވެ. ތިޔަބައިމީހުންގެ ބަފައިކަލުނަވި އިބްރާހީމްގެފާނުގެ މިއްލަތަށް ތިޔަބައިމީހުން ތަބާ ވާށެވެ! ކުރީގެ ފޮތްތަކުގައްޔާއި، މި ގުރްއާންގައި ތިޔަބައިމީހުންނަށް މުސްލިމުންގެ ނަން ދެއްވީ އެކަލާނގެއެވެ. (އެއީ) ތިޔަބައިމީހުންގެ މައްޗަށް ހެކިވެވަޑައިގަންނަވާ ބޭކަލަކުކަމުގައި ރަސޫލާ ވުމަށްޓަކައެވެ. އަދި މީސްތަކުންގެ މައްޗަށް ހެކިވާ ބަޔަކު ކަމުގައި ތިޔަބައިމީހުން ވުމަށްޓަކައެވެ. ފަހެ، ތިޔަބައިމީހުން ނަމާދު ގާއިމުކުރާށެވެ! އަދި ޒަކާތް ދޭށެވެ! އަދި ތިޔަބައިމީހުން ﷲގެ ދީންގައި ގަދަޔަށް ހިފަހައްޓާށެވެ! އެކަލާނގެއީ، ތިޔަބައިމީހުންނަށް ނަސްރު ދެއްވާ، އެހީތެރިވަންތަ ރަސްކަލާނގެއެވެ. ފަހެ، އެހީތެރިވެވޮޑިގެންވާ ކަލާނގެ މޮޅުކަމާއެވެ! އަދި ނަސްރު ދެއްވާކަލާނގެ މޮޅުކަމާއެވެ!","",""],["","","","بسم الله الرحمن الرحيم قد أفلح المؤمنون","މުއުމިނުން ކާމިޔާބުވެއްޖެކަން ކަށަވަރެވެ.","",""],["","","","الذين هم في صلاتهم خاشعون","އެއުރެންނީ، އެއުރެންގެ ނަމާދުގައި މަޑުމައިތިރިވެތިބޭ މީހުންނެވެ.","",""],["","","","والذين هم عن اللغو معرضون","އަދި އެއުރެންނީ، ބޭކާރު ވާހަކަތަކާއި، ކަންތަކުން ދުރުހެލިވެތިބޭ މީހުންނެވެ.","",""],["","","","والذين هم للزكاة فاعلون","އަދި އެއުރެންނީ، ޒަކާތް ދޭމީހުންނެވެ.","",""],["","","","والذين هم لفروجهم حافظون","އަދި އެއުރެންނީ، އެއުރެންގެ ފަރުޖުތަކަށް ރައްކާތެރިވާމީހުންނެވެ.","",""],["","","","إلا على أزواجهم أو ما ملكت أيمانهم فإنهم غير ملومين","އެއުރެންގެ އަނބިންގެމައްޗަށާއި، އެއުރެންނަށް މިލްކުވެގެންވާ އަޅުންގެމައްޗަށް މެނުވީއެވެ. ފަހެ، ހަމަކަށަވަރުން، އެއުރެންނީ (އެކަމުގައި) މަލާމާތް ލިބިގެންނުވާ މީހުންނެވެ.","",""],["","","","فمن ابتغى وراء ذلك فأولئك هم العادون","ފަހެ، އެއިން ބޭރުގައިވާ ކަމަކަށް އެދިއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ (ހުއްދަވެގެންވާ ސަރަޙައްދު) ފަހަނަޅައިދާ މީހުންނެވެ.","",""],["","","","والذين هم لأماناتهم وعهدهم راعون","އަދި އެއުރެންނީ އެއުރެންގެ އަމާނަތް ތަކަށާއި އެއުރެންގެ އަހުދުތަކަށް ރައްކާތެރިވާ މީހުންނެވެ.","",""],["","","","والذين هم على صلواتهم يحافظون","އަދި އެއުރެންނީ އެއުރެންގެ ނަމާދުތަކުގެ މައްޗަށް ރައްކާތެރިވާ މީހުންނެވެ.","",""],["","","","أولئك هم الوارثون","(ހެޔޮކަން) ވާރުތަވާ މީހުންނީ، ހަމައެއުރެންނެވެ.","",""],["","","","الذين يرثون الفردوس هم فيها خالدون","އެއުރެންނީ، ފިރުދައުސް އޭކިޔުނު ސުވަރުގެ ވާރުތަވާ މީހުންނެވެ. އެއުރެން އެތާނގައި ދެމިތިބޭހުށްޓެވެ.","",""],["","","","ولقد خلقنا الإنسان من سلالة من طين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ މަށީގެ ޚުލާޞާ އިން އިންސާނާ (އެބަހީ: އާދަމުގެފާނު) ހެއްދެވީމެވެ.","",""],["","","","ثم جعلناه نطفة في قرار مكين","ދެން ތިމަންރަސްކަލާނގެ އެ އިންސާނާ، ރައްކާތެރިތަނެއްގައި، މަނިތިއްކެއްގެ ގޮތުގައި ލެއްވީމެވެ.","",""],["","","","ثم خلقنا النطفة علقة فخلقنا العلقة مضغة فخلقنا المضغة عظاما فكسونا العظام لحما ثم أنشأناه خلقا آخر فتبارك الله أحسن الخالقين","ދެން ތިމަންރަސްކަލާނގެ އެ މަނިތިކި، ގަނޑުލޭކޮޅަކަށް ހެއްދެވީމެވެ. ދެން އެ ގަނޑުލޭކޮޅު، މަސްކޮޅަކަށް ހެއްދެވީމެވެ. ދެން އެ މަސްކޮޅު، ކަށްޓަށް ހެއްދެވީމެވެ. ދެން އެ ކަށީގައި މަސްލެއްވީމެވެ. ދެން އެހެންއުފެއްދެވުމަކުން އެ އިންސާނާ އުފެއްދެވީމެވެ. ފަހެ، އެންމެފުރިހަމައަށް ތަކެތި ހައްދަވާ ﷲ، މަތިވެރިވެވޮޑިގެންވެއެވެ.","",""],["","","","ثم إنكم بعد ذلك لميتون","ދެން ހަމަކަށަވަރުން، ތިޔަބައިމީހުން އޭގެފަހުގައި މަރުވާނެކަން ކަށަވަރެވެ.","",""],["","","","ثم إنكم يوم القيامة تبعثون","ދެން ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ގިޔާމަތް ދުވަހުން، އަލުންދިރުއްވައި މަހުޝަރަށް ފޮނުއްވާނެތެވެ.","",""],["","","","ولقد خلقنا فوقكم سبع طرائق وما كنا عن الخلق غافلين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނާ ދިމާމަތީގައި، ހަތް އުޑު ހެއްދެވީމެވެ. އަދި ޚަލްގު ތަކުންނާމެދު ޣާފިލު ވެވޮޑިގެންވާ ކަލަކުކަމުގައި ތިމަންރަސްކަލާނގެ ނުވަމެވެ.","",""],["","","","وأنزلنا من السماء ماء بقدر فأسكناه في الأرض وإنا على ذهاب به لقادرون","އަދި ތިމަންރަސްކަލާނގެ، ވަކި މިންވަރަކަށް އުޑުން ފެންބާވައިލެއްވީމެވެ. ފަހެ، އެ ފެން ތިމަންރަސްކަލާނގެ ބިމުގައި ހަރުލެއްވީމެވެ. އަދި ހަމަކަށަވަރުން، އެ ފެން (ތިޔަބައިމީހުންނަށް އަތުނުވާ ހިސާބަށް) ގެންދެވުމަށް، ތިމަންރަސްކަލާނގެ ކުޅަދުންވަންތަވެވޮޑިގެންވަމެވެ.","",""],["","","","فأنشأنا لكم به جنات من نخيل وأعناب لكم فيها فواكه كثيرة ومنها تأكلون","ފަހެ، އެ ފެނުގެ ސަބަބުން ކަދުރުރުކާއި، މޭބިސްކަދުރުގެ ބަގީޗާތައް ތިޔަބައިމީހުންނަށްޓަކައި، ތިމަންރަސްކަލާނގެ އުފެއްދެވީމެވެ. އެ ބަގީޗާތަކުގައި ތިޔަބައިމީހުންނަށްޓަކައި، ގިނަ މޭވާތައްވެއެވެ. އަދި ތިޔަބައިމީހުން ކައިއުޅެނީ، އެ ތަކެތިންނެވެ.","",""],["","","","وشجرة تخرج من طور سيناء تنبت بالدهن وصبغ للآكلين","އަދި ޠޫރުސައިނާއެވެ ކިޔާ ފަރުބަދައިން ނުކުންނަ ގަހެއް ހެއްދެވީމެވެ. (އެއީ ޒައިތޫނިގަހެވެ.) ތެލާއި، ކާމީހުންނަށްހުރި، ލައިގެންކާއެއްޗެއްގެ ގޮތުގައި އެ ގަސް ހެދެތެވެ.","",""],["","","","وإن لكم في الأنعام لعبرة نسقيكم مما في بطونها ولكم فيها منافع كثيرة ومنها تأكلون","އަދި ހަމަކަށަވަރުން، ނަޢަމް ސޫފީގައި، ތިޔަބައިމީހުންނަށް އިބްރަތެއް ވާކަން ކަށަވަރެވެ. އެ ތަކެތީގެ ބަނޑުތެރޭގައިވާ ތަކެތިން، ތިޔަބައިމީހުންނަށް (ކިރުގެ) ބުއިމެއް ތިމަންރަސްކަލާނގެ ދެއްވަމެވެ. އަދި އެ ތަކެތީގައި، ގިނަވެގެންވާ މަންފާތައް ތިޔަބައިމީހުންނަށް ވެއެވެ. އަދި އެއިން ތިޔަބައިމީހުން ކައިއުޅެމުއެވެ.","",""],["","","","وعليها وعلى الفلك تحملون","އަދި އެ ތަކެތީގެ މަތީގައްޔާއި، އުޅަނދުތަކުގައި، ތިޔަބައިމީހުން (އެއްތަނުން އަނެއްތަނަށް) އުފުއްލަވަތެވެ.","",""],["","","","ولقد أرسلنا نوحا إلى قومه فقال يا قوم اعبدوا الله ما لكم من إله غيره أفلا تتقون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ނޫޙުގެފާނު، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ގާތަށް ރަސޫލުކަމާއިގެން ފޮނުއްވީމެވެ. ފަހެ، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން ﷲއަށް އަޅުކަންކުރާށެވެ! އެކަލާނގެ ފިޔަވައި، އެހެން އިލާހަކު ތިޔަބައިމީހުންނަކަށް ނުވެއެވެ. ފަހެ، ތިޔަބައިމީހުން (އެކަލާނގެއަށް) ތަގުވާވެރި ނުވަނީހެއްޔެވެ؟","",""],["","","","فقال الملأ الذين كفروا من قومه ما هذا إلا بشر مثلكم يريد أن يتفضل عليكم ولو شاء الله لأنزل ملائكة ما سمعنا بهذا في آبائنا الأولين","ފަހެ، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންކުރެ ކާފިރުވި ބޮޑުން ބުނޫއެވެ. ތިޔަބައިމީހުންކަހަލަ އާދަމުގެދަރިޔަކުކަމުގައި މެނުވީ، މީނާ ނުވެއެވެ. އޭނާ ގަސްދުކުރަނީ، ތިޔަބައިމީހުންގެ މައްޗަށް މާތްވެގަތުމަށެވެ. ﷲ އިރާދަކުރެއްވިނަމަ (ރަސޫލުން ކަމުގައި) މަލާއިކަތުން ބާވައިލައްވައިފީހެވެ. ތިމަންމެންގެ ކުރީގައި އުޅުނު ކާބަފައިންގެ ތެރޭގައިވެސް، މިފަދަ ވާހަކައެއް ތިމަންމެން ނާހަމުއެވެ.","",""],["","","","إن هو إلا رجل به جنة فتربصوا به حتى حين","އޭނާގައި މޮޔަކަމެއްވާ ފިރިހެނަކު ކަމުގައި މެނުވީ އޭނާ ނުވެތެވެ. ފަހެ، ހިނދުކޮޅަކަށް އޭނާއާމެދު ތިޔަބައިމީހުން އިންތިޒާރުކުރާށެވެ!","",""],["","","","قال رب انصرني بما كذبون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! އެއުރެން ތިމަންއަޅާ ދޮގުކުޅަކަމަށްޓަކައި ތިމަންއަޅާޔަށް ނަސްރު ދެއްވާނދޭވެ!","",""],["","","","فأوحينا إليه أن اصنع الفلك بأعيننا ووحينا فإذا جاء أمرنا وفار التنور فاسلك فيها من كل زوجين اثنين وأهلك إلا من سبق عليه القول منهم ولا تخاطبني في الذين ظلموا إنهم مغرقون","ފަހެ، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ވަހީކުރެއްވީމެވެ. ތިމަންރަސްކަލާނގެ ބެއްލެވުމާއި، ތިމަންރަސްކަލާނގެ އެންގެވުމާއެކު، ނާކޮޅު ބަންނަވައި ހައްދަވާށެވެ! ފަހެ، ތިމަންރަސްކަލާނގެ (އަޒާބުގެ) އަމުރު ފުޅުއައިސް އުނދުނުގެ ތެރެއިން ފެންއަރައި، އުތުރިގެންފިހިނދު، ފަހެ، އެހިނދު ކޮންމެ އެއްޗަކުން (އަންހެން ފިރިހެން) ޖޯޑަކާއި، އެއުރެންގެ ތެރެއިން ހަލާކުވުމުގެ އަމުރުފުޅު އިސްވެހިނގައްޖެމީހަކު މެނުވީ، ކަލޭގެފާނުގެ އަހުލުވެރިން އެ ނާކޮޅަށް ލައްވާށެވެ! އަދި އަނިޔާވެރިވީ މީހުންނާމެދު، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ކަލޭގެފާނު ބަސް ނުދަންނަވާށެވެ! ހަމަކަށަވަރުން، އެއުރެންނީ، ޣަރަގުކުރައްވާނޭ މީހުންނެވެ.","",""],["","","","فإذا استويت أنت ومن معك على الفلك فقل الحمد لله الذي نجانا من القوم الظالمين","ފަހެ، ކަލޭގެފާނާއި، ކަލޭގެފާނުގެ އަރިހުގައިވާ މީހުން ނާކޮޅަށް އަރައި އޭގައި ހަމަޖެހޭހިނދު، ފަހެ، ކަލޭގެފާނު ވިދާޅުވާށެވެ. ﷲއަށް ހަމްދު ހުށްޓެވެ. އެކަލާނގެއީ، އަނިޔާވެރިވި މީހުންގެ ކިބައިން ތިމަންމެން ސަލާމަތްކުރެއްވި ރަސްކަލާނގެއެވެ.","",""],["","","","وقل رب أنزلني منزلا مباركا وأنت خير المنزلين","އަދި ކަލޭގެފާނު ވިދާޅުވާށެވެ! އަޅުގެ ވެރިރަސްކަލާކޮ! ބަރަކާތް ތެރި މަންޒިލަކަށް މިއަޅާ ބާލުއްވައިފާނދޭވެ! އަދި ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ، (މަންޒިލަށް) ބާލުއްވާ އެންމެހެޔޮ ރަސްކަލާނގެއެވެ.","",""],["","","","إن في ذلك لآيات وإن كنا لمبتلين","ހަމަކަށަވަރުން، އެކަމުގައި ހެކިތަކެއްވާކަން ކަށަވަރެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ (މީސްތަކުން) އިމްތިހާނުކުރައްވަމެވެ.","",""],["","","","ثم أنشأنا من بعدهم قرنا آخرين","ދެން އެއުރެންނަށްފަހު، ތިމަންރަސްކަލާނގެ އެހެން ޖީލެއްގެބަޔަކު އުފެއްދެވީމެވެ.","",""],["","","","فأرسلنا فيهم رسولا منهم أن اعبدوا الله ما لكم من إله غيره أفلا تتقون","ފަހެ، ތިމަންރަސްކަލާނގެ އެއުރެންގެގާތަށް، އެއުރެންގެ ތެރެއިން ރަސޫލަކު ފޮނުއްވީމެވެ. ތިޔަބައިމީހުން ﷲއަށް އަޅުކަން ކުރާށޭ އަންގަވަމުންނެވެ. އެކަލާނގެ ފިޔަވައި އެހެން އިލާހަކު ތިޔަބައިމީހުންނަކަށް ނުވެއެވެ. ފަހެ، ތިޔަބައިމީހުން (އެކަލާނގެއަށް) ތަގުވާވެރި ނުވަނީހެއްޔެވެ؟","",""],["","","","وقال الملأ من قومه الذين كفروا وكذبوا بلقاء الآخرة وأترفناهم في الحياة الدنيا ما هذا إلا بشر مثلكم يأكل مما تأكلون منه ويشرب مما تشربون","އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ތެރެއިން ކާފިރުވެ، އަދި އާޚިރަތާ ބައްދަލުވާނޭކަން ދޮގުކޮށްއުޅުނު، އަދި ދުނިޔޭގެ ހަޔާތުގައި ތަނަވަސްކަމާއި، ނިއުމަތެއުރެންނަށް ތިމަންރަސްކަލާނގެ ދެއްވި ބޮޑުންގެމީހުން ބުނޫއެވެ. ތިޔަބައިމީހުންކަހަލަ އާދަމުގެދަރިޔަކު ކަމުގައި މެނުވީ، މީނާ ނުވެއެވެ. ތިޔަބައިމީހުން އެ އެއްޗަކުން ކައިއުޅޭ ތަކެތިން، އޭނާވެސް ކައިއުޅެތެވެ. އަދި ތިޔަބައިމީހުން އެ އެއްޗަކުން ބޮއިއުޅޭ ތަކެތިން އޭނާވެސް ބޮއިއުޅެތެވެ.","",""],["","","","ولئن أطعتم بشرا مثلكم إنكم إذا لخاسرون","އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ކަހަލަ އާދަމުގެދަރިޔަކަށް ތިޔަބައިމީހުން ކިޔަމަންތެރިވެއްޖެނަމަ، އެހިނދު ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނީ، ގެއްލެނިވެގެންވާ ބަޔެއްކަން ކަށަވަރެވެ.","",""],["","","","أيعدكم أنكم إذا متم وكنتم ترابا وعظاما أنكم مخرجون","ހަމަކަށަވަރުން، ތިޔަބައިމީހުން މަރުވެއްޖެހިނދު، އަދި ވެއްޔާއި، ކަށްޓަށް ތިޔަބައިމީހުން ވެއްޖެހިނދު، އަލުންދިރުއްވައި ނެރުއްވާނޭކަމަށް އޭނާ ތިޔަބައިމީހުންނަށް ވައުދުކުރަނީހެއްޔެވެ؟","",""],["","","","هيهات هيهات لما توعدون","ތިޔަބައިމީހުންނަށް ވައުދުކުރައްވާ ކަންތައް ދުރުވެގެންވެއެވެ. (ވަރަށް) ދުރުވެގެންވެއެވެ.","",""],["","","","إن هي إلا حياتنا الدنيا نموت ونحيا وما نحن بمبعوثين","އެ ދިރިއުޅުމަކީ، ތިމަންމެންގެ ދުނިޔޭގެ ދިރިއުޅުން ފިޔަވައި އެހެން އެއްޗެއް ނޫނެވެ. ތިމަންމެން މަރުވަމުއެވެ. އަދި ދިރިއުޅެމުއެވެ. އަދި އަލުން ދިރުއްވައި ފޮނުއްވާނޭ ބަޔަކު ކަމުގައި ތިމަންމެން ނުވަމުއެވެ.","",""],["","","","إن هو إلا رجل افترى على الله كذبا وما نحن له بمؤمنين","ﷲއާމެދު ހަދައިގެން ދޮގެއް ބުނި ފިރިހެނަކު ކަމުގައިނޫނީ، އޭނާ ނުވެތެވެ. އަދި އޭނާޔަށް އީމާން ވާބަޔަކުކަމުގައި ތިމަންމެން ނުވަމުއެވެ.","",""],["","","","قال رب انصرني بما كذبون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! އެއުރެން ތިމަންއަޅާ ދޮގުކުޅަކަމަށްޓަކައި ތިމަންއަޅާޔަށް ނަސްރު ދެއްވާނދޭވެ!","",""],["","","","قال عما قليل ليصبحن نادمين","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ކުޑަހިނދުކޮޅަކުން އެއުރެން ހިތާމަކުރާ ބަޔަކުކަމުގައި ވާނޭކަން ކަށަވަރެވެ.","",""],["","","","فأخذتهم الصيحة بالحق فجعلناهم غثاء فبعدا للقوم الظالمين","ފަހެ، ހައްގު ގޮތުގައި އައި ގަދަފަދަ އަޑު އެއުރެން ހަލާކުކުރިއެވެ. ދެން އޮޔާދާ ކުނިތަކެއްފަދައިން ތިމަންރަސްކަލާނގެ އެއުރެން ލެއްވީމެވެ. ފަހެ، އަނިޔާވެރިވީ މީހުންނަށް ހަލާކާއި ގެއްލުންހުށްޓެވެ.","",""],["","","","ثم أنشأنا من بعدهم قرونا آخرين","ދެން އެއުރެންނަށްފަހު، ތިމަންރަސްކަލާނގެ އެހެން ޖީލު ތަކެއްގެ ބަޔަކު އުފެއްދެވީމެވެ.","",""],["","","","ما تسبق من أمة أجلها وما يستأخرون","އެއްވެސް އުއްމަތަކަށް، އެ އުއްމަތެއްގެ އަޖަލު އިހެއްނުކުރައްވާނެތެވެ. އަދި ފަހެއްވެސް ނުމެކުރައްވާނޭމެއެވެ.","",""],["","","","ثم أرسلنا رسلنا تترى كل ما جاء أمة رسولها كذبوه فأتبعنا بعضهم بعضا وجعلناهم أحاديث فبعدا لقوم لا يؤمنون","ދެން ތިމަންރަސްކަލާނގެ ރަސޫލުން އެއްބޭކަލަކަށްފަހު އަނެއްބޭކަލަކު ވަޑައިގަންނަވާގޮތުގައި ފޮނުއްވީމެވެ. ކޮންމެ އުއްމަތަކަށްވެސް އެ އުއްމަތްގެ ރަސޫލާ ވަޑައިގެންފި ކޮންމެ ހިނދެއްގައި، އެއުރެން އެބޭކަލަކު ދޮގުކުރިއެވެ. ފަހެ، އެއުރެންގެ އެއްބަޔަކު އަނެއްބަޔެއްގެ ފަހަތުން ފޮނުއްވައި ނެތިކުރެއްވީމެވެ. އަދި ދެކެވޭ ވާހަކަތަކެއްކަމުގައި ތިމަންރަސްކަލާނގެ އެއުރެން ލެއްވީމެވެ. ފަހެ، އީމާން ނުވާ ބަޔަކަށް ހަލާކާއި ގެއްލުންހުށްޓެވެ.","",""],["","","","ثم أرسلنا موسى وأخاه هارون بآياتنا وسلطان مبين","ދެން ތިމަންރަސްކަލާނގެ ހެކިތަކާއި، ބަޔާންވެގެންވާ ބާރަކާއެކު މޫސާގެފާނާއި، އެކަލޭގެފާނުގެ އަޚު، ހާރޫނުގެފާނު ތިމަންރަސްކަލާނގެ ފޮނުއްވީމެވެ.","",""],["","","","إلى فرعون وملئه فاستكبروا وكانوا قوما عالين","(އެއީ) ފިރްޢައުނާއި، އޭނާގެ ބޮޑުންގެ ގާތަށެވެ. ފަހެ، އެއުރެން ބޮޑާވެގަތެވެ. އަދި ކިބުރުވެރިވެގަތް ބަޔަކުކަމުގައި އެއުރެންވޫއެވެ.","",""],["","","","فقالوا أنؤمن لبشرين مثلنا وقومهما لنا عابدون","ފަހެ، އެއުރެން ބުނޫއެވެ. ތިމަންމެންކަހަލަ އާދަމުގެދަރި ދެމީހަކަށް ތިމަންމެން އީމާން ވާނެ ހެއްޔެވެ؟ އެ ދެމީހުންގެ ގައުމުގެމީހުން، ތިމަންމެންނަށް ކިޔަމަންވާ އަޅުންކަމުގައިވާ ޙާލު ގައެވެ.","",""],["","","","فكذبوهما فكانوا من المهلكين","ފަހެ، އެއުރެން އެ ދެބޭކަލުން ދޮގުކުޅައޫއެވެ. ދެން ހަލާކުކުރައްވައި، ނެތިކުރެއްވި މީހުންގެ ތެރެއިން އެއުރެންވޫއެވެ.","",""],["","","","ولقد آتينا موسى الكتاب لعلهم يهتدون","އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް ފޮތް ދެއްވީމެވެ. (އެއީ) އެއުރެން ތެދުމަގު ލިބިގަތުމަށްޓަކައެވެ.","",""],["","","","وجعلنا ابن مريم وأمه آية وآويناهما إلى ربوة ذات قرار ومعين","އަދި މަރިޔަމްގެފާނުގެ ދަރިކަލުންނާއި، އެ ދަރިކަލުންގެ މައިކަމަނާ (ކުޅަދުންވަންތަކަމުގެ) ހެތްކެއް ކަމުގައި، ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ. އަދި ހަމަޖެހޭ ދިރިއުޅުމަކާއި، ފެންއާރުތަކެއްގެވެރި އުސްބިމެއްގައި، ތިމަންރަސްކަލާނގެ އެ ދެމައިކަނބަލުންނަށް ހިޔާވަހިކަން ދެއްވީމެވެ.","",""],["","","","يا أيها الرسل كلوا من الطيبات واعملوا صالحا إني بما تعملون عليم","(އެކަލާނގެ ވަހީކުރެއްވިއެވެ.) އޭ ރަސޫލުންނޭވެ! ހަލާލު ރަނގަޅު ތަކެތިން ތިޔަބޭކަލުން ފަރިއްކުޅުއްވައި އުޅުއްވާށެވެ! އަދި ސާލިހު ޢަމަލުކުރައްވާށެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެއީ، ތިޔަބޭކަލުން ކުރައްވާ ޢަމަލުތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وإن هذه أمتكم أمة واحدة وأنا ربكم فاتقون","އަދި ހަމަކަށަވަރުން، މިއީ އެއް އުއްމަތެއް ކަމުގައިވާ، ތިޔަބައިމީހުންގެ އުއްމަތެވެ. އަދި ތިމަންރަސްކަލާނގެއީ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއެވެ. ފަހެ، ތިޔަބައިމީހުން ތިމަންރަސްކަލާނގެއަށް ބިރުވެތިވެ، ތަގުވާވެރިވާށެވެ!","",""],["","","","فتقطعوا أمرهم بينهم زبرا كل حزب بما لديهم فرحون","ފަހެ، އެއުރެންގެ ދީންގެ ކަންތައް، އެއުރެންގެ މެދުގައި ތަފާތު ބައިތަކަކަށް އެއުރެން ބައިކުރޫއެވެ. ކޮންމެބަޔަކުމެ، އެ ބަޔަކުގެ ގާތުގައިވާ ގޮތާމެދު އުފަލުން ތިބެތެވެ.","",""],["","","","فذرهم في غمرتهم حتى حين","ފަހެ، އެއުރެންގެ މަގުފުރެދުމުގެތެރޭގައި، ހިނދުކޮޅަކަށް ދާނދެން ކަލޭގެފާނު އެއުރެން ދޫކޮށްލައްވާށެވެ!","",""],["","","","أيحسبون أنما نمدهم به من مال وبنين","މުދަލާއި، ދަރިންގެ ތެރެއިން ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްވާ ދެއްވުން އެއީ، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ހެޔޮކަންތައް ދެއްވުމުގައި އަވަސްވެވޮޑިގަންނަވަނީކަމަށް އެއުރެން ހީކުރަނީ ހެއްޔެވެ؟ އަދި ކިއެއްތަ! އެއުރެންނަށް (އެކަމުގެ ހަގީގަތް) ނޭނގެނީއެވެ.","",""],["","","","نسارع لهم في الخيرات بل لا يشعرون","މުދަލާއި، ދަރިންގެ ތެރެއިން ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްވާ ދެއްވުން އެއީ، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ހެޔޮކަންތައް ދެއްވުމުގައި އަވަސްވެވޮޑިގަންނަވަނީކަމަށް އެއުރެން ހީކުރަނީ ހެއްޔެވެ؟ އަދި ކިއެއްތަ! އެއުރެންނަށް (އެކަމުގެ ހަގީގަތް) ނޭނގެނީއެވެ.","",""],["","","","إن الذين هم من خشية ربهم مشفقون","ހަމަކަށަވަރުން، އެއުރެންނީ، އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ބިރުވެތިވުމުން އެކަލާނގެ އަޒާބަށް ބިރުވެތިވާ މީހުންނެވެ.","",""],["","","","والذين هم بآيات ربهم يؤمنون","އަދި އެއުރެންނީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ އާޔަތްތަކަށް އީމާންވާ މީހުންނެވެ.","",""],["","","","والذين هم بربهم لا يشركون","އަދި އެއުރެންނީ، އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ޝަރީކު ނުކުރާ މީހުންނެވެ.","",""],["","","","والذين يؤتون ما آتوا وقلوبهم وجلة أنهم إلى ربهم راجعون","އަދި އެއުރެންނީ އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް، ހަމަކަށަވަރުން، އެއުރެން އެނބުރިދާނޭކަމާމެދު އެއުރެންގެ ހިތްތައް ބިރުވެތިވެގެންވާ ޙާލު (ސަދަގާތްގެ ގޮތުން) އެއުރެން ދޭއެއްޗެއް ދޭމީހުންނެވެ.","",""],["","","","أولئك يسارعون في الخيرات وهم لها سابقون","އެއުރެން އެންމެންނީ، ހެޔޮކަންތަކުގައި އަވަސްވެގަންނަ މީހުންނެވެ. އަދި އެއުރެންނީ އެކަންތަކުގައި ކުރިއަރައިދާ މީހުންނެވެ.","",""],["","","","ولا نكلف نفسا إلا وسعها ولدينا كتاب ينطق بالحق وهم لا يظلمون","އަދި އެއްވެސް ނަފްސަކަށް، އެ ނަފްސަކަށް ކުޅަދާނަވެގެންވާ މިންވަރަށް މެނުވީ، ތިމަންރަސްކަލާނގެ ތަކުލީފެއް ނުޖައްސަވަމެވެ. އަދި ހައްގު ގޮތުގައި ބަސްބުނާ ފޮތެއް، ތިމަންރަސްކަލާނގެ ހަޒުރަތު ގައިވެއެވެ. އަދި އެއުރެންނަކަށް ބޭއިންސާފެއް ނުކުރައްވާހުށްޓެވެ.","",""],["","","","بل قلوبهم في غمرة من هذا ولهم أعمال من دون ذلك هم لها عاملون","އަދި ކިއެއްތަ! އެއުރެންގެ ހިތްތައްވަނީ، މި (ގުރްއާން) އާމެދު ނޭނގުމެއްގެ ތެރޭގައެވެ. އަދި އެއުރެން ކުރަމުންދާ ޢަމަލުތަކުގެ އިތުރަށް، އެއުރެންނަށް އެހެން (ނުބައި) ޢަމަލު ތަކެއްވެއެވެ.","",""],["","","","حتى إذا أخذنا مترفيهم بالعذاب إذا هم يجأرون","އެއުރެންގެ ތެރެއިން، ތަނަވަސްކަމުގައި ހައްދުފަހަނަޅައިފައިވާ މީހުންނަށް، ތިމަންރަސްކަލާނގެ އަޒާބު ފޮނުއްވައި، އެއުރެން ގެންދަވައިފުމަށް ދާނދެނެވެ. އެހާރުން، އެއުރެން ރޮއިހޭރި، ސަލާމަތަށްއެދި ގޮވާނެތެވެ.","",""],["","","","لا تجأروا اليوم إنكم منا لا تنصرون","(އެއުރެންނަށް އަންގަވާހުށްޓެވެ.) ތިޔަބައިމީހުން މިއަދު ރޮއިހޭރި ނުގޮވާށެވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަކަށް، ތިމަންރަސްކަލާނގެ ހަޒުރަތަކުން ނަސްރުވެރިކަމެއް ނުލިބޭނެތެވެ.","",""],["","","","قد كانت آياتي تتلى عليكم فكنتم على أعقابكم تنكصون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ބާވައިލެއްވި އާޔަތްތައް، ތިޔަބައިމީހުންނަށް (އިއްވައި) ކިޔެވޭ ކަމުގައިވިއެވެ. ފަހެ، ތިޔަބައިމީހުން އަނެއްފަރާތަށް އެނބުރި، ފުރަގަސްދޭ ބަޔަކު ކަމުގައި ވީމުއެވެ.","",""],["","","","مستكبرين به سامرا تهجرون","އެ ގުރްއާނާމެދު ބޮޑާވެގަންނަ ޙާލު ގައެވެ. ތިޔަބައިމީހުން ރޭގަނޑުގެ ވަގުތުގައި (އެ ގުރްއާނަށް) މަލާމާތްކޮށް ވާހަކަދައްކަން ތިބޭހިނދުގައެވެ.","",""],["","","","أفلم يدبروا القول أم جاءهم ما لم يأت آباءهم الأولين","ފަހެ، އެއުރެން ގުރްއާނާމެދު ވިސްނުން ހިންގައި، ފިކުރުނުކުރަނީ ހެއްޔެވެ؟ ނުވަތަ އެއުރެންގެ އިހުގެ ކާބަފައިންގެ ގާތަށް ނާންނަކަމެއް އެއުރެންގެ ގާތަށް އައީހެއްޔެވެ؟","",""],["","","","أم لم يعرفوا رسولهم فهم له منكرون","ނުވަތަ އެއުރެން އެކަލޭގެފާނަށް އިންކާރު ކޮށް، ދެކޮޅުހަދަނީ އެއުރެންގެ ރަސޫލާ، އެއުރެންނަށް ނޭނގެނީ ހެއްޔެވެ؟","",""],["","","","أم يقولون به جنة بل جاءهم بالحق وأكثرهم للحق كارهون","ނުވަތަ އެކަލޭގެފާނުގެ ކިބައިގައި، މޮޔަކަމެއްވާކަމަށް އެއުރެން ބުނަނީ ހެއްޔެވެ؟ އަދި ކިއެއްތަ! (އެހެންނަކުންނޫނެވެ.) އެއުރެންނަށް އެކަލޭގެފާނު ހައްގު ގޮތް ގެނެސްދެއްވިއެވެ. އަދި އެއުރެންކުރެ ގިނަމީހުންނީ، ހައްގަށް ނުރުހޭބަޔެކެވެ.","",""],["","","","ولو اتبع الحق أهواءهم لفسدت السماوات والأرض ومن فيهن بل أتيناهم بذكرهم فهم عن ذكرهم معرضون","ހައްގު ގުރުއާނެއުރެންގެ އެދުންތަކަށް ތަބާ ވީނަމަ، އުޑުތަކާއި، ބިމާއި، އެތާނގައިވާހާ ބަޔަކު ފާސިދުވެ، ނުބައިވެގެން ހިނގައްޖައީހެވެ. އަދި ކިއެއްތަ! ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ހަނދާންކޮށްދެނިވި ގުރްއާންގެނެސްދެއްވީމެވެ. ފަހެ، އެއުރެންނީ އެ ގުރްއާނަށް ފުރަގަސްދީ އެނބުރިގަންނަ ބަޔެކެވެ.","",""],["","","","أم تسألهم خرجا فخراج ربك خير وهو خير الرازقين","ނުވަތަ ކަލޭގެފާނު، އެއުރެންގެ ކިބައިން އުޖޫރައަކަށް އެދިވަޑައިގަންނަވަނީތޯއެވެ؟ ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ދެއްވާ ސަވާބު މާހެޔޮކަން ބޮޑެވެ. އަދި އެކަލާނގެއީ، ރިޒްގު ދެއްވާ އެންމެހެޔޮ ރަސްކަލާނގެއެވެ.","",""],["","","","وإنك لتدعوهم إلى صراط مستقيم","ހަމަކަށަވަރުން، ކަލޭގެފާނު ސީދާވެގެންވާ ތެދުމަގަށް އެއުރެންނަށް ގޮވައިލައްވާކަން ކަށަވަރެވެ.","",""],["","","","وإن الذين لا يؤمنون بالآخرة عن الصراط لناكبون","އަދި ހަމަކަށަވަރުން، އާޚިރަތަށް އީމާން ނުވާމީހުން، ތެދުމަގުން އެއްކިބާވެގެންވާކަން ކަށަވަރެވެ.","",""],["","","","ولو رحمناهم وكشفنا ما بهم من ضر للجوا في طغيانهم يعمهون","އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ރަހުމަތް ލައްވައި، އެއުރެންގެ ކިބައިގައިވާ ދަތިކަން ތިމަންރަސްކަލާނގެ ފިއްލެވިނަމަވެސް، އެއުރެންގެ މަގުފުރެދުމުގައި ދެވޭނުދެވޭތަނެއް ނޭނގޭގޮތުގައި، އެއުރެން ދެމިތިބީހެވެ.","",""],["","","","ولقد أخذناهم بالعذاب فما استكانوا لربهم وما يتضرعون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އަޒާބު ދެއްވައި އެއުރެން ހިއްޕެވީމެވެ. ދެންވެސް އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް، އެއުރެން މަޑުމައިތިރިވެ، އަޅުކަންކޮށް ދުއާ ކޮށެއް ނަހަދަތެވެ.","",""],["","","","حتى إذا فتحنا عليهم بابا ذا عذاب شديد إذا هم فيه مبلسون","ގަދަފަދަވެގެންވާ އަޒާބެއްގެ ދޮރު، ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް ހުޅުއްވައިފުމަށް ދާނދެނެވެ. އެހާރުން އެ އަޒާބުގެތެރޭގައި އުންމީދުކެނޑިގެންވާ ބަޔަކު ކަމުގައި އެއުރެންވާނެތެވެ.","",""],["","","","وهو الذي أنشأ لكم السمع والأبصار والأفئدة قليلا ما تشكرون","އެކަލާނގެއީ، ތިޔަބައިމީހުންނަށްޓަކައި، އިވުމާއި، ފެނުމާއި، ހިތްތައް އުފެއްދެވި ރަސްކަލާނގެއެވެ. ތިޔަބައިމީހުން ޝުކުރުކުރަނީ، ވަރަށްވެސް މަދުންނެވެ.","",""],["","","","وهو الذي ذرأكم في الأرض وإليه تحشرون","އަދި އެކަލާނގެއީ، ބިމުގައި ތިޔަބައިމީހުން އުފެއްދެވި ރަސްކަލާނގެއެވެ. އަދި (ގިޔާމަތް ދުވަހުން) ތިޔަބައިމީހުން އެއްކުރައްވާހުށީ، އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","وهو الذي يحيي ويميت وله اختلاف الليل والنهار أفلا تعقلون","އަދި ދިރުއްވަނީވެސް، އަދި މަރުގަންނަވަނީވެސް، ހަމައެކަލާނގެއެވެ. އަދި ރެޔާއިދުވާލުގެ ތަފާތު ކުރެއްވުން މިލްކުވެގެންވަނީވެސް، އެކަލާނގެއަށެވެ. ފަހެ، ތިޔަބައިމީހުން ނުވިސްނަނީ ހެއްޔެވެ؟","",""],["","","","بل قالوا مثل ما قال الأولون","އަދި ކިއެއްތަ! އިހުގެ މީހުން ބުނިފަދައިން، އެއުރެން ބުނޫއެވެ.","",""],["","","","قالوا أإذا متنا وكنا ترابا وعظاما أإنا لمبعوثون","އެއުރެން ބުނޫއެވެ. ތިމަންމެން މަރުވެ، އަދި ވެއްޔާއި، ކަށްޓަށްވެއްޖެހިނދު، ހަމަކަށަވަރުން، އަލުން ދިރުމަކަށް ފޮނުއްވާނޭ ބަޔަކު ކަމުގައި ތިމަންމެން ވާނޭހެއްޔެވެ؟","",""],["","","","لقد وعدنا نحن وآباؤنا هذا من قبل إن هذا إلا أساطير الأولين","ހަމަކަށަވަރުން، މީގެކުރިންވެސް ތިމަންމެންނަށާއި، ތިމަންމެންގެ ކާބަފައިންނަށް، މިކަންތައް ވައުދުކުރެއްވިއެވެ. އެވޭލާމީހުން ދައްކައި އުޅުނު ފުލޯކުވާހަކަތަކެއް ކަމުގައި، މެނުވީ މިކަންތައް ނުވެއެވެ.","",""],["","","","قل لمن الأرض ومن فيها إن كنتم تعلمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ބިމާއި، އެތާނގައިވާހާ ބަޔަކާއި، ތަކެއްޗެއް މިލްކުވެގެންވަނީ، ކާކަށްހެއްޔެވެ؟ ތިޔަބައިމީހުން އެކަން ދަންނަކަމުގައި ވާނަމައެވެ.","",""],["","","","سيقولون لله قل أفلا تذكرون","އެއުރެން ދަންނަވާނެތެވެ. (މިލްކުވެރިކަންވަނީ) ﷲއަށެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ފަހެ، ތިޔަބައިމީހުން ހަނދުމަ ނުކުރަނީ ހެއްޔެވެ؟","",""],["","","","قل من رب السماوات السبع ورب العرش العظيم","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަތް އުޑުގެ ވެރިޔަކީ، އަދި މާތްވެގެންވާ ޢަރްޝުގެ ވެރިޔަކީ ކާކުހެއްޔެވެ؟","",""],["","","","سيقولون لله قل أفلا تتقون","އެއުރެން ދަންނަވާނެތެވެ. (ވެރިކަންވަނީ) ﷲއަށެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ފަހެ، ތިޔަބައިމީހުން (އެކަލާނގެޔަށް) ތަގުވާވެރި ނުވަނީ ހެއްޔެވެ؟","",""],["","","","قل من بيده ملكوت كل شيء وهو يجير ولا يجار عليه إن كنتم تعلمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެފަރާތެއްގެ އަތްޕުޅުގައި އެންމެހާ ތަކެތީގެ މިލްކުވެރިކަންވާ ފަރާތަކީ، ކޮބައިހެއްޔެވެ؟ އެންމެހާ ތަކެތި ރައްކާތެރިކުރައްވަނީ، އެކަލާނގެއެވެ. އެކަލާނގެއާ ދެކޮޅަށް (އެއްވެސް މީހަކަށް) ރައްކާތެރިކަމެއް ނުދެވޭނެތެވެ. ތިޔަބައިމީހުން (އެކަން) ދަންނަކަމުގައި ވާނަމައެވެ.","",""],["","","","سيقولون لله قل فأنى تسحرون","އެއުރެން ދަންނަވާނެތެވެ. (މިލްކުވެރިކަންވަނީ) ﷲއަށެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ފަހެ، ތިޔަބައިމީހުންނަށް (އެކަންކަން) އޮޅެނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","بل أتيناهم بالحق وإنهم لكاذبون","އަދި ކިއެއްތަ! އެއުރެންގެ ގާތަށް ތިމަންރަސްކަލާނގެ ހައްގު ގޮތް ގެނެސްދެއްވީމެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެންނީ ދޮގުހަދާ ބަޔެއްކަން ކަށަވަރެވެ.","",""],["","","","ما اتخذ الله من ولد وما كان معه من إله إذا لذهب كل إله بما خلق ولعلا بعضهم على بعض سبحان الله عما يصفون","ﷲ، އެއްވެސް ދަރިކަލަކު ނުހިއްޕަވަތެވެ. އަދި އެކަލާނގެއާއެކު، އެހެންއެއްވެސް އިލާހަކު ނުވެއެވެ. އެހެންވީނަމަ، ކޮންމެ އިލާހަކުމެ، އެ އިލާހަކު ހެދިތަކެއްޗާއިގެން ހިނގައްޖައީހެވެ. އަދި އޭގެ އެއްބަޔަކު އަނެއްބަޔަކަށްވުރެ މަތިވެރިވެގެން ހިނގައްޖައީސްކަން ކަށަވަރެވެ. އެއުރެން އެ ސިފަކުރާ ގޮތްތަކުން ﷲ ހުސްތާހިރު ވެވޮޑިގެންވެއެވެ.","",""],["","","","عالم الغيب والشهادة فتعالى عما يشركون","(އެކަލާނގެއީ) ނުފެންނަ ކަންތަކާއި، ފެންނަ ކަންތައް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. ފަހެ، އެއުރެން ޝަރީކުކުރާ ތަކެއްޗަށްވުރެން އެކަލާނގެ މަތިވެރިވެވޮޑިގެންވެއެވެ.","",""],["","","","قل رب إما تريني ما يوعدون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އަޅުގެ ވެރިރަސްކަލާކޮ! އެއުރެންނަށް ވައުދުކުރައްވާ ކަންތައް، ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެ ތިމަންއަޅާޔަށް ދެއްކެވިޔަސް، އަޅުގެ ވެރިރަސްކަލާކޮ! ފަހެ، އަނިޔާވެރިވީ މީހުންގެ ތެރޭގައި ތިމަންއަޅާ ނުލައްވާނދޭވެ!","",""],["","","","رب فلا تجعلني في القوم الظالمين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އަޅުގެ ވެރިރަސްކަލާކޮ! އެއުރެންނަށް ވައުދުކުރައްވާ ކަންތައް، ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެ ތިމަންއަޅާޔަށް ދެއްކެވިޔަސް، އަޅުގެ ވެރިރަސްކަލާކޮ! ފަހެ، އަނިޔާވެރިވީ މީހުންގެ ތެރޭގައި ތިމަންއަޅާ ނުލައްވާނދޭވެ!","",""],["","","","وإنا على أن نريك ما نعدهم لقادرون","ހަމަކަށަވަރުން، އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ވައުދުކުރައްވާ ކަންތައް ކަލޭގެފާނަށް ދެއްކެވުމަށް ތިމަންރަސްކަލާނގެ ކުޅަދުންވަންތަކަން ކަށަވަރެވެ.","",""],["","","","ادفع بالتي هي أحسن السيئة نحن أعلم بما يصفون","އެންމެހެޔޮ ރިވެތިގޮތުން ކަލޭގެފާނު ނުބައިކަންތައް ދުރުކުރައްވާށެވެ! އެއުރެންބުނެ ސިފަކުރާ ގޮތްތައް، ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގަތުން ބޮޑެވެ.","",""],["","","","وقل رب أعوذ بك من همزات الشياطين","އަދި ކަލޭގެފާނު ވިދާޅުވާށެވެ! އަޅުގެ ވެރިރަސްކަލާކޮ! ޝައިތާނުންގެ ވަސްވާސްތަކުން ދުރުކުރެއްވުންއެދި، އިބަރަސްކަލާނގެ ހަޒުރަތުން، ތިމަންއަޅާ ރައްކާތެރިކަން ލިބިގަންނަމެވެ.","",""],["","","","وأعوذ بك رب أن يحضرون","އަދި އަޅުގެ ވެރިރަސްކަލާކޮ! އެ ޝައިތާނުން ތިމަންއަޅާގެ ގާތަށް ޙާޒިރުު ވެދާނެކަމަށްޓަކައި އިބަރަސްކަލާނގެ ހަޒުރަތުން ރައްކާތެރިކަން ލިބިގަންނަމެވެ.","",""],["","","","حتى إذا جاء أحدهم الموت قال رب ارجعون","އެއުރެންކުރެ މީހެއްގެ ގާތަށް މަރު އަތުވެއްޖައުމަން ދާނދެނެވެ. އެހިނދު އޭނާ ބުނެތެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ތިމަންއަޅާ (ދުނިޔޭގެ ހަޔާތަށް) އަލުން އަނބުރައި ފޮނުއްވާނދޭވެ!","",""],["","","","لعلي أعمل صالحا فيما تركت كلا إنها كلمة هو قائلها ومن ورائهم برزخ إلى يوم يبعثون","(އެއީ) ތިމަންފަހަތަށް ދޫކުޅަ ކަންތަކުގައި ސާލިހު ޢަމަލުކުރުމުގެ އެދުމުގައެވެ. ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ހަމަކަށަވަރުން، އެއީ އޭނާ ބުނެލާ ބަހެކެވެ. އަދި އެއުރެންގެ ފަހަތުގައިވަނީ ފަރުދާއެކެވެ. އެއުރެން އަލުން ދިރުމަކަށް ފޮނުއްވާ ދުވަހަށްދާނދެނެވެ.","",""],["","","","فإذا نفخ في الصور فلا أنساب بينهم يومئذ ولا يتساءلون","ފަހެ، ތާޅަފިލި ފުމެލައްވައިފިހިނދު، ފަހެ، އެއުރެންގެ މެދުގައި އެދުވަހަކުން ނަސަބު ތަކެއް ނޯންނާނެތެވެ. އަދި އެކަކު އަނެކެއްގެ ކިބައިން ކަންތަކަށްއެދި ސުވާލެއްވެސް ނުކުރާނޭމެއެވެ.","",""],["","","","فمن ثقلت موازينه فأولئك هم المفلحون","ފަހެ، އެމީހެއްގެ (ހެޔޮ ޢަމަލުތަކުގެ) ތިލަފަތްތައް ބަރުވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، ދިންނަވާނޭ މީހުންނަކީ ހަމައެއުރެންނެވެ.","",""],["","","","ومن خفت موازينه فأولئك الذين خسروا أنفسهم في جهنم خالدون","އަދި އެމީހެއްގެ (ހެޔޮ ޢަމަލުތަކުގެ) ތިލަފަތްތައް ލުއިވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ އެއުރެންގެ ނަފްސުތައް، ނަގައިލި މީހުންނެވެ. ނަރަކައިގައި އެއުރެން ދެމިތިބޭނެތެވެ.","",""],["","","","تلفح وجوههم النار وهم فيها كالحون","ނަރަކައިގެ އަލިފާން އެއުރެންގެ މޫނުތައް އަންދާނެތެވެ. އަދި އެއުރެން އެތާނގައި ރުޅިމޫނު ހަދައިގެން ތިބޭނެތެވެ.","",""],["","","","ألم تكن آياتي تتلى عليكم فكنتم بها تكذبون","(އެއުރެންނަށް އަންގަވާނެތެވެ.) ތިމަންރަސްކަލާނގެ އާޔަތްތައް ތިޔަބައިމީހުންނަށް ކިޔަވައިދެވޭ ކަމުގައި ނުވޭހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުން އެ އާޔަތްތައް ދޮގުކުރާކަމުގައި ވީމުއެވެ.","",""],["","","","قالوا ربنا غلبت علينا شقوتنا وكنا قوما ضالين","އެއުރެން ދަންނަވާނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ތިމަންމެންގެ އަބާއްޖަވެރިކަން ތިމަންމެންގެ މައްޗަށް ގަދަވެގަތީއެވެ. އަދި މަގުފުރެދިގެންވާ ބަޔަކު ކަމުގައި ތިމަންމެން ވީމުއެވެ.","",""],["","","","ربنا أخرجنا منها فإن عدنا فإنا ظالمون","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ތިމަންމެން އެ ނަރަކައިން ނެރުއްވައިފާނދޭވެ! ފަހެ، ތިމަންމެން (ކާފިރުކަމުގެ ތެރެޔަށް) އެނބުރި ހިނގައްޖެނަމަ، ފަހެ، ހަމަކަށަވަރުން، ތިމަންމެންވާހުށީ އަނިޔާވެރިން ކަމުގައެވެ.","",""],["","","","قال اخسئوا فيها ولا تكلمون","އެކަލާނގެ ވަހީކުރައްވާނެތެވެ. ތިޔަބައިމީހުން ނިކަމެތިކަމާއެކު ހިމޭންވެ އެތާތިބޭށެވެ! އަދި ތިޔަބައިމީހުން، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ބަސް ނުދަންނަވާށެވެ!","",""],["","","","إنه كان فريق من عبادي يقولون ربنا آمنا فاغفر لنا وارحمنا وأنت خير الراحمين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އަޅުންގެތެރެއިން ބަޔަކުވިއެވެ. އެއުރެން ބުނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެން އީމާން ވެއްޖައީމުއެވެ. ފަހެ، އަޅަމެންނަށް ފާފަފުއްސަވައި، އަޅަމެންނަށް ރަހުމަތް ލައްވާނދޭވެ! އިބަރަސްކަލާނގެއީ، ރަހުމަތް ލައްވާ އެންމެހެޔޮ ރަސްކަލާނގެއެވެ.","",""],["","","","فاتخذتموهم سخريا حتى أنسوكم ذكري وكنتم منهم تضحكون","ފަހެ، އެއުރެންނީ، ފުރައްސާރަކުރެވޭ ބަޔެއްކަމުގައި ތިޔަބައިމީހުން ހަދައިފީމުއެވެ. ތިމަންރަސްކަލާނގެ ހަނދުމަކުޅައުންމަތިން އެއުރެން ތިޔަބައިމީހުން ހަނދުމަނެތިކޮށްފުމަށް ދާނދެނެވެ. އަދި އެއުރެންނާމެދު މަލާމާތްކޮށް، ހޭނ ބަޔަކު ކަމުގައި ތިޔަބައިމީހުން ވީމުއެވެ.","",""],["","","","إني جزيتهم اليوم بما صبروا أنهم هم الفائزون","އެއުރެން ކެތްތެރިވިކަމަށްޓަކައި، މިއަދު ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް (ހެޔޮ) ޖަޒާދެއްވީމެވެ. ހަމަކަށަވަރުން، އެއުރެންނީ، ހަމަ ނަސީބުވެރިންނެވެ.","",""],["","","","قال كم لبثتم في الأرض عدد سنين","އެކަލާނގެ ވަހީކުރައްވާނެތެވެ. ތިޔަބައިމީހުން ކިތައް އަހަރު ބިމުގައި ތިބީމުހެއްޔެވެ؟","",""],["","","","قالوا لبثنا يوما أو بعض يوم فاسأل العادين","އެއުރެން ދަންނަވާނެތެވެ. ތިމަންމެން ތިބީ، އެންމެ ދުވަހަކުއެވެ. ނުވަތަ ދުވަހެއްގެ ބައެއްގައެވެ. ފަހެ، ހިސާބުކޮށް އަދަދުކުރާ މީހުންނާ ސުވާލުކުރައްވާށެވެ!","",""],["","","","قال إن لبثتم إلا قليلا لو أنكم كنتم تعلمون","އެކަލާނގެ ވަހީކުރައްވާނެތެވެ. ދާދި ކުޑަ ދުވަސްކޮޅަކު މެނުވީ، ތިޔަބައިމީހުން ލަސްވެ ނުތިބެމުއެވެ. ތިޔަބައިމީހުންނަށް އެކަން އެނގޭކަމުގައި ވީނަމައެވެ.","",""],["","","","أفحسبتم أنما خلقناكم عبثا وأنكم إلينا لا ترجعون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން ހެއްދެވީ، ބޭކާރުގޮތުގައި، ކުޅިވަރަށްކަމަށާއި، ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ރުޖޫއަ ނުކުރައްވާނޭކަމަށް، ތިޔަބައިމީހުން ފަހެ، ހީކުޅައީ ހެއްޔެވެ؟","",""],["","","","فتعالى الله الملك الحق لا إله إلا هو رب العرش الكريم","ފަހެ، ރަސްވަންތަ، ހައްގުވަންތަ ﷲ، މަތިވެރިވެވޮޑިގެންފިއެވެ. އެކަލާނގެ މެނުވީ، އިލާހަކު ނެތެވެ. އެއީ މާތްވެގެންވާ ޢަރްޝުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["","","","ومن يدع مع الله إلها آخر لا برهان له به فإنما حسابه عند ربه إنه لا يفلح الكافرون","ﷲއާއެކު އެހެން އިލާހަކަށް އަޅުކަންކޮށްއުޅޭ މީހަކު، އެކަމުގެ މައްޗަށް އެމީހަކަށް (ލިބޭނޭ) އެއްވެސް ދަލީލެއް ނެތެވެ. ފަހެ، އެމީހެއްގެ ހިސާބު ބެއްލެވުން ވާކަންކަށަވަރީ، އެމީހާގެ ވެރިރަސްކަލާނގެ ހަޒުރަތު ގައެވެ. ހަމަކަށަވަރުން، ކާފިރުންނެއް ނުދިނޭނެތެވެ.","",""],["","","","وقل رب اغفر وارحم وأنت خير الراحمين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އަޅުގެ ވެރިރަސްކަލާކޮ! ފާފަފުއްސަވައި ރަހުމަތް ލައްވާނދޭވެ! އިބަރަސްކަލާނގެއީ، ރަހުމަތް ލައްވާ، އެންމެހެޔޮ ރަސްކަލާނގެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم سورة أنزلناها وفرضناها وأنزلنا فيها آيات بينات لعلكم تذكرون","(މިއީ) ސޫރަތެކެވެ. ތިމަންރަސްކަލާނގެ، އެ ސޫރަތް ބާވައިލެއްވީ އަދި އެ ސޫރަތް ގައިވާ ކަންތައްތައް ކަނޑައަޅުއްވައި ފަރުޟުކުރެއްވީ، އަދި ފާޅުވެ ބަޔާން ވެގެންވާ ހެކިތައް، ތިމަންރަސްކަލާނގެ އެ ސޫރަތުގައި ބާވައިލެއްވީ، ތިޔަބައިމީހުން ހަނދުމަކުރުމަށްޓަކައެވެ.","",""],["","","","الزانية والزاني فاجلدوا كل واحد منهما مائة جلدة ولا تأخذكم بهما رأفة في دين الله إن كنتم تؤمنون بالله واليوم الآخر وليشهد عذابهما طائفة من المؤمنين","ޒިނޭކުރާ އަންހެނާއާއި، ޒިނޭކުރާ ފިރިހެނާއާއި ދެމީހުންކުރެ ކޮންމެ މީހަކުގެ ގައިގައި، ސަތޭކަ އެތިފަހަރުން (ޙައްދު) ޖަހާށެވެ! އަދި ﷲއަށާއި އާޚިރަތް ދުވަހަށް ތިޔަބައިމީހުން އީމާން ވާކަމުގައިވަނީނަމަ، ﷲގެ ދީންގައި އެ ދެމީހުންނާމެދު އޯގާވެރިކަމެއް ތިޔަބައިމީހުން ނުބަހައްޓާހުށިކަމެވެ! އަދި އެ ދެމީހުންނަށް ދެވޭ އުގޫބާތް، މުއުމިނުންގެ ބަޔަކު ދެކޭހުށިކަމެވެ!","",""],["","","","الزاني لا ينكح إلا زانية أو مشركة والزانية لا ينكحها إلا زان أو مشرك وحرم ذلك على المؤمنين","ޒިނޭކުރާ ފިރިހެނާ، ޒިނޭކުރާ އަންހެނަކާ، ނުވަތަ ޝަރީކުކުރާ އަންހެނަކާ ނޫނީ ނުއިންނާނެތެވެ. އަދި ޒިނޭކުރާ އަންހެނާ (ދަންނާށެވެ!) ޒިނޭކުރާ ފިރިހެނަކު ނުވަތަ ޝަރީކުކުރާ ފިރިހެނަކު ނޫނީ އެކަނބުލޭގެއަކާ ނުއިންނާނެތެވެ. އަދި މުއުމިނުންގެ މައްޗަށް އެކަން ހަރާމްކުރައްވާފައިވެއެވެ. (ނޯޓު: މި އާޔަތުގައިވާ ހުކުމް ވަނީ މި ސޫރަތުގެ ތިރީސް ދެވަނަ އާޔަތުން ނަސްޚު ވެފައިކަމަށް އިލްމުވެރިން ދެކެވަޑައިގަންނަވައެވެ.)","",""],["","","","والذين يرمون المحصنات ثم لم يأتوا بأربعة شهداء فاجلدوهم ثمانين جلدة ولا تقبلوا لهم شهادة أبدا وأولئك هم الفاسقون","ޢިއްފަތް ތެރި އަންހެނުންނަށް ގަޛްފުކުރާމީހުން (އެކަމުގެ މައްޗަށް) ހަތަރު ހެކިން ނުގެނައިނަމަ، ފަހެ، އެއުރެންގެގައިގައި އަށްޑިހަ އެތިފަހަރުން (ޙައްދު) ޖަހާށެވެ! އަދި ދުވަހަކުވެސް އެއުރެންގެ ހެކިބަހެއް ތިޔަބައިމީހުން ގަބޫލު ނުކުރާށެވެ! އަދި އެއުރެންނީ، ހަމަ، ފާސިގުންނެވެ.","",""],["","","","إلا الذين تابوا من بعد ذلك وأصلحوا فإن الله غفور رحيم","އެއަށްފަހު ތައުބާވެ (ޢަމަލުތައް) އިސްލާހު ކޮށްފިމީހުން މެނުވީއެވެ. ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","والذين يرمون أزواجهم ولم يكن لهم شهداء إلا أنفسهم فشهادة أحدهم أربع شهادات بالله إنه لمن الصادقين","އަދި އެއުރެންގެ އަމިއްލަ ނަފްސުތައް މެނުވީ ހެކިދޭބަޔަކު އެއުރެންނަށް ލިބިގެންނުވާ ޙާލު، އެއުރެންގެ އަނބީންނަށް ގަޛްފުކުރާމީހުން (ދަންނާށެވެ!) ފަހެ، އެއިން ކޮންމެ މީހަކު، ﷲ ގަންދީ ހަތަރު ހުވައިން ހުވާކުރުން ހުށްޓެވެ. ހަމަކަށަވަރުން، އޭނާއީ ތެދުވެރިންގެ ތެރެއިންވާ މީހަކު ކަމަށެވެ.","",""],["","","","والخامسة أن لعنت الله عليه إن كان من الكاذبين","އަދި ފަސްވަނަ ހުވާކުރުން ހުށްޓެވެ. އޭނާއީ ދޮގުވެރިންގެ ތެރެއިންވާ މީހަކު ކަމުގައިވާނަމަ، ހަމަކަށަވަރުން، ﷲގެ ލައުނަތް އޭނާގެ މައްޗަށް ހުރިކަމަށެވެ.","",""],["","","","ويدرأ عنها العذاب أن تشهد أربع شهادات بالله إنه لمن الكاذبين","ހަމަކަށަވަރުން، އޭނާއީ ދޮގުވެރިންގެ ތެރެއިންވާ މީހެއްކަމަށް ﷲ ގަންދީ އެކަނބުލޭގެ ހަތަރުހުވައިން ހުވާކުރުމުން، އެކަނބުލޭގެ ކިބައިން އުގޫބާތް (އެބަހީ: ޙައްދު ޖެހުން) ކެނޑޭނެތެވެ.","",""],["","","","والخامسة أن غضب الله عليها إن كان من الصادقين","އަދި ފަސްވަނަ ހުވާކުރުން ހުށްޓެވެ. އޭނާއަކީ ތެދުބުނާ މީހުންގެ ތެރެއިންވާ މީހަކު ކަމުގައިވާނަމަ، ހަމަކަށަވަރުން، ﷲގެ ކޯފާ އެކަނބުލޭގެ މައްޗަށް ހުރިކަމަށެވެ.","",""],["","","","ولولا فضل الله عليكم ورحمته وأن الله تواب حكيم","އަދި ﷲގެ ފަޟްލު ވަންތަކަމާއި، އެކަލާނގެ ރަހުމަތް ވަންތަކަން ތިޔަބައިމީހުންގެ މައްޗަށް ނުވާނަމައެވެ. (އެބަހީ: އެކަލާނގެ ރަހުމަތް ވަންތަކަން ނުވާނަމަ، ތިޔަބައިމީހުން ފަޟީޙަތްކުރައްވައި ހަލާކުކުރައްވައިފީހެވެ.) އަދި ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ތައުބާ ގަބޫލުކުރައްވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","إن الذين جاءوا بالإفك عصبة منكم لا تحسبوه شرا لكم بل هو خير لكم لكل امرئ منهم ما اكتسب من الإثم والذي تولى كبره منهم له عذاب عظيم","ހަމަކަށަވަރުން، ބޮޑުވެގެންވާ ދޮގުވާހަކައާއިގެން އައި މީހުންނަކީ، ތިޔަބައިމީހުންގެ ތެރެއިންވާ ބަޔަކު މީހުންނެވެ. އެއީ ތިޔަބައިމީހުންނަށްހުރި ނުބައެއްކަމުގައި ތިޔަބައިމީހުން ހީނުކުރާށެވެ! އަދި ކިއެއްތަ! އެއީ ތިޔަބައިމީހުންނަށްހުރި ހެވެކެވެ. އެއުރެންކުރެ ކޮންމެމީހަކަށްމެ، ފާފައިގެ ތެރެއިން އެމީހަކު ހޯދައިގަތްކަމެއް ވެއެވެ. އަދި އެއުރެންގެ ތެރެއިން އެކަމުގެ ބޮޑުބައި ލިބިގަތްމީހާ (ދަންނާށެވެ!) އޭނާއަށް ބޮޑުވެގެންވާ އަޒާބު ހުށްޓެވެ.","",""],["","","","لولا إذ سمعتموه ظن المؤمنون والمؤمنات بأنفسهم خيرا وقالوا هذا إفك مبين","އެވާހަކަ އިވުނުހިނދު، މުއުމިނު ފިރިހެނުންނާއި، މުއުމިނު އަންހެނުން އެއުރެންގެ އަމިއްލަ ނަފްސު ތަކާމެދުގައި ހެޔޮކޮށް ހީނުކުޅައީ ކީއްވެގެން ބާވައެވެ؟ އަދި މިއީ، ބަޔާންވެ ފާޅުވެގެންހުރި ބޮޑުދޮގެކޭ ނުބުނީ ކީއްވެގެން ބާވައެވެ؟","",""],["","","","لولا جاءوا عليه بأربعة شهداء فإذ لم يأتوا بالشهداء فأولئك عند الله هم الكاذبون","އެކަމުގެ މައްޗަށް އެއުރެން ހަތަރުހެކިން ނުގެނައީ ކީއްވެގެން ހެއްޔެވެ؟ ފަހެ، އެއުރެން (އެކަން ދެނެހުރި) ހެކިން ނުގެނައިހިނދު، ފަހެ، ﷲގެ ހަޒުރަތުގައި އެއުރެންނީ ހަމަ ދޮގުހަދާ މީހުންނެވެ.","",""],["","","","ولولا فضل الله عليكم ورحمته في الدنيا والآخرة لمسكم في ما أفضتم فيه عذاب عظيم","ދުނިޔެއާއި، އާޚިރަތުގައި ތިޔަބައިމީހުންގެ މައްޗަށް ﷲގެ ފަޟްލު ވަންތަކަމާއި، އެކަލާނގެ ރަހުމަތް ވަންތަކަން ނެތްނަމަ، ތިޔަބައިމީހުން ދައްކަމުން ގެންދިޔަ ވާހަކަތަކާމެދު، ބޮޑުވެގެންވާ އަޒާބެއް، ތިޔަބައިމީހުންގައި ބީހިއްޖައީސްކަން ކަށަވަރެވެ.","",""],["","","","إذ تلقونه بألسنتكم وتقولون بأفواهكم ما ليس لكم به علم وتحسبونه هينا وهو عند الله عظيم","ތިޔަބައިމީހުންގެ ދޫތަކުން އެ ވާހަކަތައް ލިބިގަންނަމުންދިޔަ ހިނދުގައެވެ. އަދި ތިޔަބައިމީހުންނަށް އެކަމާމެދު އެނގުމެއްނުވާ ކަންތަކުގެ ވާހަކަ، ތިޔަބައިމީހުންގެ އަނގަތަކުން ބުނަމުއެވެ. އަދި ﷲގެ ހަޒުރަތުގައި އެކަންތައް ބޮޑުކަމެއްކަމުގައިވާ ޙާލު، އެއީ ކުޑަ ކަމެއްކަމުގައި ތިޔަބައިމީހުން ހީކުރަމުއެވެ.","",""],["","","","ولولا إذ سمعتموه قلتم ما يكون لنا أن نتكلم بهذا سبحانك هذا بهتان عظيم","ތިޔަބައިމީހުންނަށް އެވާހަކަ އަޑުއިވުނުހިނދު (މިހެން) ތިޔަބައިމީހުން ނުބުނީ ކީއްވެގެން ހެއްޔެވެ؟ މިވާހަކަ ދެއްކުމަކީ ތިމަންމެން ކޮށްގެންވާނެ ކަމެއްނޫނެވެ. އިބަރަސްކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! މިއީ ބޮޑުވެގެންވާ ބުހުތާނު ދޮގެކެވެ.","",""],["","","","يعظكم الله أن تعودوا لمثله أبدا إن كنتم مؤمنين","ތިޔަބައިމީހުންނީ މުއުމިނުން ކަމުގައިވާނަމަ، އެފަދަކަމަކަށް ދުވަހަކުވެސް އެނބުރި ނުދިއުމަށް ﷲ ތިޔަބައިމީހުންނަށް ވައުޒު އިއްވަވަތެވެ.","",""],["","","","ويبين الله لكم الآيات والله عليم حكيم","އަދި ﷲ ތިޔަބައިމީހުންނަށްޓަކައި އާޔަތްތައް ބަޔާން ކޮށްދެއްވަތެވެ. ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","إن الذين يحبون أن تشيع الفاحشة في الذين آمنوا لهم عذاب أليم في الدنيا والآخرة والله يعلم وأنتم لا تعلمون","ހަމަކަށަވަރުން، އީމާންވި މީހުންގެ ތެރޭގައި ހުތުރުކަންބޮޑު ފާފައިގެ ވާހަކައާއި، ޢަމަލު، ފެތުރިގެންދިއުމަށް ލޯބިކުރާމީހުން (ދަންނާށެވެ!) ދުނިޔެއާއި އާޚިރަތުގައި ވޭންދެނިވި އަޒާބު އެމީހުންނަށް ހުށްޓެވެ. ﷲ ދެނެވޮޑިގެންވެތެވެ. އަދި ތިޔަބައިމީހުންނަކަށް ނޭނގެތެވެ.","",""],["","","","ولولا فضل الله عليكم ورحمته وأن الله رءوف رحيم","ތިޔަބައިމީހުންގެ މައްޗަށް ﷲގެ ފަޟްލު ވަންތަކަމާއި، އެކަލާނގެ ރަހުމަތް ވަންތަކަން ނުވާނަމަ، އަދި ހަމަކަށަވަރުން، ﷲއީ، ނުހަނު އޯގާވަންތަ، ރަޙީމްވަންތަ ކަލާނގެކަމުގައި ނުވާނަމަ (ތިޔަބައިމީހުންގެ މައްޗަށް ވަގުތުން ކޯފާ ފޮނުއްވައިފީހެވެ.)","",""],["","","","يا أيها الذين آمنوا لا تتبعوا خطوات الشيطان ومن يتبع خطوات الشيطان فإنه يأمر بالفحشاء والمنكر ولولا فضل الله عليكم ورحمته ما زكى منكم من أحد أبدا ولكن الله يزكي من يشاء والله سميع عليم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ޝައިތާނާގެ ފިޔަވަޅުތަކަށް ތަބާ ނުވާށެވެ! އަދި ޝައިތާނާގެ ފިޔަވަޅުތަކަށް ތަބާ ވާމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އެ ޝައިތާނާ ހުތުރުކަންބޮޑު ފާފައާއި، ނުބައިކަންތަކަށް އަމުރުކުރެތެވެ. އަދި ﷲގެ ފަޟްލު ވަންތަކަމާއި، އެކަލާނގެ ރަހުމަތް ވަންތަކަން ތިޔަބައިމީހުންގެ މައްޗަށް ނުވާނަމަ، ތިޔަބައިމީހުންގެ ތެރެއިން އެކަކުވެސް، ދުވަހަކުވެސް ފާފަތަކުން ތާހިރުވެ ސާފެއްނުވީހެވެ. އެހެނެއްކަމަކު، ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކު ތާހިރުކުރައްވައި، ސާފުކުރައްވަތެވެ. ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ولا يأتل أولو الفضل منكم والسعة أن يؤتوا أولي القربى والمساكين والمهاجرين في سبيل الله وليعفوا وليصفحوا ألا تحبون أن يغفر الله لكم والله غفور رحيم","ތިޔަބައިމީހުންގެ ތެރެއިން ދީލަތިކަމާއި، ތަނަވަސްކަމުގެ ވެރިން، ގާތްތިމާގެ މީހުންނަށާއި، މިސްކީނުންނަށާއި، ﷲގެ މަގުގައި ހިޖުރަކުޅަ މީހުންނަށް، ނުދިނުމަށް ހުވާނުކުރާހުށިކަމެވެ! އަދި އެއުރެން އަފޫ ކޮށް މާފުކުރާހުށިކަމެވެ! ﷲ ތިޔަބައިމީހުންނަށް ފާފަފުއްސެވުމަކަށް ތިޔަބައިމީހުން ނޭދެމުހެއްޔެވެ؟ ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","إن الذين يرمون المحصنات الغافلات المؤمنات لعنوا في الدنيا والآخرة ولهم عذاب عظيم","ހަމަކަށަވަރުން، ޢިއްފަތް ތެރި، ޣަފްލަތު ތެރި (އެބަހީ: ފާފަކުރުމުގެ ޚިޔާލު ވެސްނެތް) މުއުމިނު އަންހެނުންނަށް ގަޛްފުކުރާ މީހުންނަށް، ދުނިޔެއާއި، އާޚިރަތުގައި ލައުނަތް ލައްވާފައިވެއެވެ. އަދި އެއުރެންނަށް ބޮޑުވެގެންވާ އަޒާބު ހުށްޓެވެ.","",""],["","","","يوم تشهد عليهم ألسنتهم وأيديهم وأرجلهم بما كانوا يعملون","އެއުރެންގެ މައްޗަށް އެއުރެންގެ ދޫތަކާއި، އަތްތަކާއި ފައިތައް، އެއުރެން ކޮށްއުޅުނު ކަންތައްތަކާމެދު ހެކިވާ ދުވަހުންނެވެ.","",""],["","","","يومئذ يوفيهم الله دينهم الحق ويعلمون أن الله هو الحق المبين","އެދުވަހުން ﷲ، އެއުރެންނަށް، އެއުރެންގެ ހައްގު ޖަޒާ ހަމަޔަށް ދެއްވާނެތެވެ. އަދި ހަމަކަށަވަރުން، ﷲއީ، ބަޔާން ވެގެންވާގޮތުގައި، ހަމަ ހައްގުވަންތަ ކަލާނގެކަން އެއުރެންނަށް އެނގޭނެތެވެ.","",""],["","","","الخبيثات للخبيثين والخبيثون للخبيثات والطيبات للطيبين والطيبون للطيبات أولئك مبرءون مما يقولون لهم مغفرة ورزق كريم","ނުބައި އަންހެނުން ނުބައި ފިރިހެނުންނަށެވެ. ނުބައި ފިރިހެނުން ނުބައި އަންހެނުންނަށެވެ. ރަނގަޅު އަންހެނުން ރަނގަޅު ފިރިހެނުންނަށެވެ. ރަނގަޅު ފިރިހެނުން ރަނގަޅު އަންހެނުންނަށެވެ. އެއުރެން (އެބަހީ: ނުބައިމީހުން) ބުނާ ބުނުންތަކުން އެއުރެން (އެބަހީ: ރަނގަޅުމީހުން) ބަރީއަވެގެންވެއެވެ. ފާފަފުއްސެވުމާއި، ދީލަތިވެގެންވާ ރިޒްގެއުރެންނަށް ހުށްޓެވެ.","",""],["","","","يا أيها الذين آمنوا لا تدخلوا بيوتا غير بيوتكم حتى تستأنسوا وتسلموا على أهلها ذلكم خير لكم لعلكم تذكرون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ ގެތައް ނޫން އެހެން ގެތަކަށް އެ ގެތަކުގެ އަހުލުވެރިންނަށް ސަލާމް ކޮށް އިޒުނަ ލިބިގެންފުމަށްދާނދެން ނުވަންނާށެވެ! އެގޮތް ތިޔަބައިމީހުންނަށް ހެޔޮކަންބޮޑެވެ. (އެއީ) ތިޔަބައިމީހުން ހަނދުމަކުރުމަށްޓަކައެވެ.","",""],["","","","فإن لم تجدوا فيها أحدا فلا تدخلوها حتى يؤذن لكم وإن قيل لكم ارجعوا فارجعوا هو أزكى لكم والله بما تعملون عليم","ފަހެ، އެ ގެތަކުން ތިޔަބައިމީހުންނަށް އެކަކުވެސް ނުފެނުނުނަމަ، ތިޔަބައިމީހުންނަށް އިޒުނަ ދެވިއްޖައުމަށްދާނދެން އެ ގެތަކަށް ތިޔަބައިމީހުން ނުވަންނާށެވެ! އަދި ތިޔަބައިމީހުން އެނބުރި ހިނގައިދާށޭ ތިޔަބައިމީހުންނަށް ބުނެވިއްޖެނަމަ، ފަހެ، ތިޔަބައިމީހުން އެނބުރި ހިނގައިދާށެވެ! އެގޮތް ތިޔަބައިމީހުންނަށް ސާފުކަންބޮޑެވެ. ﷲއީ، ތިޔަބައިމީހުންކުރާ ކަންތައް، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ليس عليكم جناح أن تدخلوا بيوتا غير مسكونة فيها متاع لكم والله يعلم ما تبدون وما تكتمون","އެ ގެތަކުގައި ތިޔަބައިމީހުންނަށް ބޭނުމެއްވާ، އަދި މީހުންނޫޅޭ ގެތަކަށް ތިޔަބައިމީހުން ވަނުމަކުން، ތިޔަބައިމީހުންގެ މައްޗަކަށް ކުށެއްނެތެވެ. އަދި ތިޔަބައިމީހުން ފާޅުކުރާ ކަންތަކާއި، ވަންހަނާކުރާ ކަންތައް ﷲ ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","قل للمؤمنين يغضوا من أبصارهم ويحفظوا فروجهم ذلك أزكى لهم إن الله خبير بما يصنعون","މުއުމިނު ފިރިހެނުންނަށް، އެއުރެންގެ ބެލުންތައް ތިރިކުރުމަށާއި، އެއުރެންގެ ފަރުޖުތައް ރައްކާތެރިކުރުމަށް ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެގޮތް އެއުރެންނަށްޓަކައި، ތާހިރު ކަން ބޮޑެވެ. ހަމަކަށަވަރުން، ﷲއީ، އެއުރެން ކުރާކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وقل للمؤمنات يغضضن من أبصارهن ويحفظن فروجهن ولا يبدين زينتهن إلا ما ظهر منها وليضربن بخمرهن على جيوبهن ولا يبدين زينتهن إلا لبعولتهن أو آبائهن أو آباء بعولتهن أو أبنائهن أو أبناء بعولتهن أو إخوانهن أو بني إخوانهن أو بني أخواتهن أو نسائهن أو ما ملكت أيمانهن أو التابعين غير أولي الإربة من الرجال أو الطفل الذين لم يظهروا على عورات النساء ولا يضربن بأرجلهن ليعلم ما يخفين من زينتهن وتوبوا إلى الله جميعا أيه المؤمنون لعلكم تفلحون","އަދި މުއުމިނު އަންހެނުންނަށް އެކަނބަލުންގެ ބެލުންތައް ތިރިކުރުމަށާއި، އެކަނބަލުންގެ ފަރުޖުތައް ރައްކާތެރިކުރުމަށް ކަލޭގެފާނު ވިދާޅުވާށެވެ! އަދި އެކަނބަލުންގެ ޒީނަތުގެ ތެރެއިން ފާޅުވެގެންވާތަން ފިޔަވައި (އެބަހީ: މޫނާއި ދެއަތްތިލަ ފިޔަވައި) އެކަނބަލުންގެ ޒީނަތް ފާޅުނުކުރާހުށިކަމެވެ! އަދި އެކަނބަލުންގެ ބުރުގާތައް، އެކަނބަލުންގެ ކަރުވަޅުތަކުގައި އަޅައިނިވައިކުރާހުށިކަމެވެ! އަދި އެކަނބަލުންގެ ފިރިންނަށް، ނުވަތަ އެކަނބަލުންގެ ބަފައިންނަށް، ނުވަތަ އެކަނބަލުންގެ ފިރިންގެ ބަފައިންނަށް، ނުވަތަ އެކަނބަލުންގެ ފިރިހެން ދަރިންނަށް، ނުވަތަ އެކަނބަލުންގެ ފިރިންގެ ފިރިހެން ދަރިންނަށް، ނުވަތަ އެކަނބަލުންގެ އަޚުންނަށް، ނުވަތަ އެކަނބަލުންގެ އަޚުންގެ ފިރިހެން ދަރިންނަށް، ނުވަތަ އެކަނބަލުންގެ އުޚްތުންގެ ފިރިހެން ދަރިންނަށް، ނުވަތަ އެކަނބަލުންގެ ތެރެއިންވާ އަންހެނުންނަށް، ނުވަތަ އެކަނބަލުންނަށް މިލްކުވެގެންވާ އަޅުންނަށް، ނުވަތަ ފިރިހެނުންގެ ތެރެއިން އެދުންވެރި ކަމެއް ނުހިނގާވަރުގެ ގެންގުޅޭ މީހުންނަށް، ނުވަތަ އަންހެނުންގެ ޢައުރަތައް ނޭނގޭވަރުގެ ކުޑަކުއްޖާއަށް މެނުވީ، އެކަނބަލުންގެ ޒީނަތް ފާޅުނުކުރާހުށިކަމެވެ! އަދި އެކަނބަލުންގެ (ގަހަނާއާއި) ޒީނަތުގެ ތެރެއިން، ވަންހަނާވެފައިވާ ތަކެތި އެންގުމަށްޓަކައި، ފައިތިލަތަކުން (ބިމުގައި) އެކަނބަލުން ނުތަޅާހުށިކަމެވެ! އޭ މުއުމިނުންނޭވެ! ތިޔަބައިމީހުން އެންމެން ﷲއަށް ތައުބާ ވާށެވެ! (އެއީ) ތިޔަބައިމީހުން ދިންނަވައި، ނަސީބު ލިބުމަށްޓަކައެވެ.","",""],["","","","وأنكحوا الأيامى منكم والصالحين من عبادكم وإمائكم إن يكونوا فقراء يغنهم الله من فضله والله واسع عليم","އަދި ތިޔަބައިމީހުންގެ ތެރެއިން މީހުނާ ނުއިނދެތިބޭ މީހުން، ތިޔަބައިމީހުން (މީހުނާ) ދެވާށެވެ! އަދި ތިޔަބައިމީހުންގެ ފިރިހެން އަޅުންނާއި، އަންހެން އަޅުންގެ ތެރެއިން ހެޔޮލަފާ މީހުންވެސްމެއެވެ. އެއުރެންނީ، ފަގީރުން ކަމުގައިވާނަމަ، އެކަލާނގެ ފަޟްލު ވަންތަކަމުން، އެކަލާނގެ އެއުރެން މުއްސަނދިކުރައްވައިފާނެތެވެ. ﷲއީ، ތަނަވަސްވަންތަ، މޮޅަށްދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وليستعفف الذين لا يجدون نكاحا حتى يغنيهم الله من فضله والذين يبتغون الكتاب مما ملكت أيمانكم فكاتبوهم إن علمتم فيهم خيرا وآتوهم من مال الله الذي آتاكم ولا تكرهوا فتياتكم على البغاء إن أردن تحصنا لتبتغوا عرض الحياة الدنيا ومن يكرههن فإن الله من بعد إكراههن غفور رحيم","އަދި ކާވެނިވުމުގެ މަގެއް ނުފެންނަ މީހުން ޢިއްފަތް ތެރިވެ ތިބޭހުށިކަމެވެ! ﷲ، އެކަލާނގެ ފަޟްލު ވަންތަކަމުގެ ތެރެއިން، އެއުރެން މުއްސަނދިކުރައްވައި، އެކަން ފުއްދަވައި ދެއްވައިފުމަށް ދާނދެނެވެ. އަދި ތިޔަބައިމީހުންނަށް މިލްކުވެގެންވާ އަޅުންގެ ތެރެއިން މިނިވަންވުމުގެ ލިޔުން އެދޭ މީހުންނާމެދު، (ދަންނާށެވެ!) ފަހެ، އެފަދަ ލިޔުން ތިޔަބައިމީހުން އެމީހުންނަށް ލިޔެދޭށެވެ! އެއުރެންގެކިބައިން ހެޔޮގޮތެއް ތިޔަބައިމީހުންނަށް އެނގިއްޖެނަމައެވެ. އަދި ތިޔަބައިމީހުންނަށް ދެއްވާފައިވާ ﷲގެ މުދަލުން، ތިޔަބައިމީހުން އެއުރެންނަށްދޭށެވެ! އަދި އެކަނބަލުން ޢިއްފަތް ތެރިވެ ރައްކާތެރިވެ ތިބުމަށް ގަސްދު ކޮށްގެން ތިބޭނަމަ، ދުނިޔޭގެ ދިރިއުޅުމަށް ހޯދާ މުދަލެއް އެދިގަތުމުގެގޮތުން ތިޔަބައިމީހުންގެ ޒުވާން އަންހެން އަޅުން، ޒިނޭކުރުމުގެ މައްޗަށް މަޖުބޫރު ނުކުރާށެވެ! އެކަނބަލުންނަށް، އެކަމަށް މަޖުބޫރުކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އެކަނބަލުން މަޖުބޫރު ވެވުމަށްފަހު، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ولقد أنزلنا إليكم آيات مبينات ومثلا من الذين خلوا من قبلكم وموعظة للمتقين","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށް ބަޔާން ކޮށްދެނިވި އާޔަތް ތަކާއި، ތިޔަބައިމީހުންގެ ކުރިން އިސްވެދިޔަމީހުންގެ މިސާލާއި، ތަގުވާވެރިވެ، ބިރުވެތިވާ މީހުންނަށް ވައުޒުގެ ބަސްފުޅުތައް، ތިމަންރަސްކަލާނގެ ބާވައިލެއްވީމެވެ.","",""],["","","","الله نور السماوات والأرض مثل نوره كمشكاة فيها مصباح المصباح في زجاجة الزجاجة كأنها كوكب دري يوقد من شجرة مباركة زيتونة لا شرقية ولا غربية يكاد زيتها يضيء ولو لم تمسسه نار نور على نور يهدي الله لنوره من يشاء ويضرب الله الأمثال للناس والله بكل شيء عليم","ﷲއީ، އުޑުތަކާއި، ބިމުގެ ނޫރެވެ. އެކަލާނގެ ނޫރު ފުޅުގެ މިސާލަކީ، އެއްފަރާތުން އަނެއްފަރާތަށް ފޫވެއްޓިފައިނުވާ، އާނގެއްގެ މިސާލެވެ. އެ އާނގުގެ ތެރޭގައި، ބައްތިއެއްވެއެވެ. އެ ބައްތިވަނީ ބިއްލޫރިގަނޑެއްގެ ތެރޭގައެވެ. އެ ބިއްލޫރިގަނޑު، ރަންމުތުގެ ތަރިއެއްފަދައެވެ. އެ ބައްތި ދިއްލެނީ، ބަރަކާތް ތެރި ޒައިތޫނި ގަހަކުންނެވެ. އިރުމަތީގެ ގަހެއްނޫނެވެ. ހުޅަނގުގެ ގަހެއްވެސް ނުމެނޫންމެއެވެ. އެ ގަހުގެ ތެޔޮ، އޭގައި އަލިފާން ނުބީހުނަސް އަލިކުރާން ގާތްވެފައިވެއެވެ. އަލިކަމެއްގެ މައްޗަށްހުރި އަލިކަމެކެވެ. އަދި ﷲ، އެކަލާނގެ އިރާދަކުރެއްވި މީހަކަށް، އެކަލާނގެ ނޫރު ފުޅަށް މަގުދައްކަވަތެވެ. އަދި ﷲ، މީސްތަކުންނަށް މިސާލުތައް ޖައްސަވައިދެއްވަތެވެ. ﷲއީ، ކޮންމެކަމެއްމެ، މޮޅަށްދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","في بيوت أذن الله أن ترفع ويذكر فيها اسمه يسبح له فيها بالغدو والآصال","އެތަންތާނގައި، އެކަލާނގެ ނަންފުޅު ހަނދުމަކުރުމަށާއި، އެތަންތަން މަތިވެރިކޮށް އުފުލުމަށް، ﷲ އިޒުނަ ދެއްވާފައިވާ ގެތަކެއްގައެވެ. (އެބަހީ: މިސްކިތްތަކެއްގައެވެ.) ހެނދުނާއި ހަވީރު، އެތާނގައި އެކަލާނގެއަށް ތަސްބީހަ ކިޔައި އުޅެތެވެ.","",""],["","","","رجال لا تلهيهم تجارة ولا بيع عن ذكر الله وإقام الصلاة وإيتاء الزكاة يخافون يوما تتقلب فيه القلوب والأبصار","އެއީ ފިރިހެނުންތަކެކެވެ. (އެބަހީ: ތަސްބީހަ ކިޔައި ނަމާދުކޮށް އުޅެނީ ފިރިހެނުންތަކެކެވެ.) ވިޔަފާރިއެއް ނުވަތަ އެހެންއެއްވެސް ވިއްކުމެއް ﷲގެ މަތިން ހަނދުމަކުޅައުމުންނާއި، ނަމާދު ގާއިމުކުޅައުމުންނާއި، ޒަކާތް ދިނުމުން، އެއުރެން މަޝްޣޫލު ކޮށް ދުރުކޮށެއް ނުލަތެވެ. އެދުވަހެއްގައި، ހިތްތަކާއި، ލޯތައް އެފުށްމިފުށަށް އެނބުރިއުޅޭ ދުވަހަށް، އެއުރެން ބިރުވެތިވެތެވެ.","",""],["","","","ليجزيهم الله أحسن ما عملوا ويزيدهم من فضله والله يرزق من يشاء بغير حساب","އެއުރެން ޢަމަލުކުޅަ އެންމެހެޔޮގޮތަށް، ﷲއެއުރެންނަށް ހެޔޮ ޖަޒާ ދެއްވުމަށްޓަކައެވެ. އަދި އެކަލާނގެ ފަޟްލު ވަންތަކަމުގެ ތެރެއިން، އެއުރެންނަށް އިތުރުކޮށްދެއްވުމަށްޓަކައެވެ. ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް، ވަކި މިންވަރެއްނެތި ރިޒްގު ދެއްވަތެވެ.","",""],["","","","والذين كفروا أعمالهم كسراب بقيعة يحسبه الظمآن ماء حتى إذا جاءه لم يجده شيئا ووجد الله عنده فوفاه حسابه والله سريع الحساب","ކާފިރުވި މީހުން (ދަންނާށެވެ!) އެއުރެންގެ ޢަމަލުތައްވަނީ، ތަނަވަސް ހުސްބިމެއްގައިވާ އަވާމެންދުރެއް ފަދައިންނެވެ. އަނގަހިއްކައިގެންފައިވާ މީހާ، އެއީ ފެންކަމަށް ހީކުރެތެވެ. އޭނާ އޭގެކައިރިޔަށް އަތުވެއްޖެ ހިނދު، އޭނާޔަށް (އޭނާ ހީކުރި) އެއްޗެއް ނުފެނުނެވެ. އަދި އޭނާޔަށް އެތަނުން ފެނުނީ، ﷲގެ ނިޔާފުޅެވެ. ފަހެ، އެމީހާގެ ހިސާބު، އެކަލާނގެ އެމީހާޔަށް ހަމަޔަށް ދެއްވައެވެ. ﷲއީ، ހިސާބު ބެއްލެވުން އަވަސްވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","أو كظلمات في بحر لجي يغشاه موج من فوقه موج من فوقه سحاب ظلمات بعضها فوق بعض إذا أخرج يده لم يكد يراها ومن لم يجعل الله له نورا فما له من نور","ނުވަތަ ފުން ކަނޑެއްގައިވާ އަނދިރިތަކެއްފަދައެވެ. އެ ކަނޑުގައި ފެތުރިފައިވަނީ، މަތިމައްޗަށް ހުންނަ ރާޅުތަކެވެ. އޭގެމަތިން ވިލާތައްވެއެވެ. މަތިމައްޗަށްހުރި އަނދިރިތަކެކެވެ. އެމީހާގެ އަތް ނެރުނަސް، އެ ފެންނާންވެސް ގާތްނުވެއެވެ. ފަހެ، އެމީހަކަށް ﷲ އަލިކަމެއްލައްވާފައި ނުވާމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާޔަށް އެއްވެސް އަލިކަމެއް ނުވެއެވެ.","",""],["","","","ألم تر أن الله يسبح له من في السماوات والأرض والطير صافات كل قد علم صلاته وتسبيحه والله عليم بما يفعلون","ހަމަކަށަވަރުން، ﷲއަށް، އުޑުތަކާއި، ބިމުގައިވާހާ ބަޔަކު، އަދި ދޫނިސޫފާސޫފިތައް އެ ތަކެތީގެ ފިޔަތައް ދަމާލައިގެން އުދުހިއުދުހި ތިބޭހިނދު، އެކަލާނގެއަށް ތަސްބީހަ ކިޔަކިޔައި ތިބޭކަން ކަލޭގެފާނަށް އެނގިވަޑައިނުގަންނަވަނީތޯއެވެ؟ ކޮންމެ އެއްޗަކަށްމެ، އެ އެއްޗެއްގެ އަޅުކަމާއި، އެ އެއްޗެއްގެ ތަސްބީހަ އެނގިފައިވެއެވެ. ﷲއީ، އެއުރެން ކުރާ ކަންތައް މޮޅަށްދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ولله ملك السماوات والأرض وإلى الله المصير","އަދި އުޑުތަކާއި، ބިމުގެ ވެރިކަންވަނީ، ﷲއަށެވެ. އަދި (އެންމެހާ ތަކެތި) ރުޖޫއަ ވުން ވަނީ، ﷲގެ ހަޒުރަތަށެވެ.","",""],["","","","ألم تر أن الله يزجي سحابا ثم يؤلف بينه ثم يجعله ركاما فترى الودق يخرج من خلاله وينزل من السماء من جبال فيها من برد فيصيب به من يشاء ويصرفه عن من يشاء يكاد سنا برقه يذهب بالأبصار","ހަމަކަށަވަރުން، ﷲ، ވިލާ ހިންގަވާތީ ކަލޭގެފާނު ދެކެވަޑައި ނުގަންނަވަމުތޯއެވެ؟ ދެން އެ ވިލާތައް އެއްކުރައްވަތެވެ. ދެން މަތިމައްޗަށް ހުންނަ ވިލާތަކެއްކަމުގައި ލައްވަތެވެ. ފަހެ، އެ ވިލާތަކުގެ ތެރެއިން، ވާރޭ ނުކުމެގެން އަންނާތީ ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނޫއެވެ. އަދި އުޑުގައިވާ، ފަރުބަދަތައް ފަދަ ބިޔަ ވިލާތަކުން، އެކަލާނގެ ގަނޑުފެން ވެއްސަވަތެވެ. ފަހެ، އެކަލާނގެ އިރާދަކުރައްވާ މީހެއްގައި އެ ޖައްސަވަތެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވާ މީހެއްގެ ކިބައިން އެ، ދުރުކުރައްވަތެވެ. އޭގެ ވިދުވަރުގެ އަލިގަދަކަމުން، ލޯތަކުގެ ފެނުން ގެންދިޔުމާ ގާތްކުރެތެވެ.","",""],["","","","يقلب الله الليل والنهار إن في ذلك لعبرة لأولي الأبصار","ﷲ، ރޭދުވާ ބަދަލުކުރައްވަތެވެ. ހަމަކަށަވަރުން، ބުއްދީގެ އަހުލުވެރިންނަށް އެކަމުގައި، އިބްރަތެއްވާކަން ކަށަވަރެވެ.","",""],["","","","والله خلق كل دابة من ماء فمنهم من يمشي على بطنه ومنهم من يمشي على رجلين ومنهم من يمشي على أربع يخلق الله ما يشاء إن الله على كل شيء قدير","އަދި ދިރޭކޮންމެ އެއްޗެއް، ﷲ، ފެނުން ހައްދަވާފައިވެއެވެ. ފަހެ، ބަނޑުލައިލޫދެމުން ހިނގާ ތަކެތި އޭގެތެރެއިންވެއެވެ. އަދި ދެފައިން ހިނގާ ތަކެތިވެސް އޭގެތެރެއިންވެއެވެ. އަދި ހަތަރެސްފައިން ހިނގާ ތަކެތިވެސް އޭގެތެރެއިންވެއެވެ. ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ އެއްޗެއް ހައްދަވަތެވެ. ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެކަމެއްގެ މައްޗަށްމެ ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","لقد أنزلنا آيات مبينات والله يهدي من يشاء إلى صراط مستقيم","ހަމަކަށަވަރުން، ބަޔާން ކޮށްދެނިވި އާޔަތް ތަކެއް ތިމަންރަސްކަލާނގެ ބާވައިލެއްވީމެވެ. އަދި ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ސީދާވެގެންވާ ތެދުމަގަށް މަގުދައްކަވަތެވެ.","",""],["","","","ويقولون آمنا بالله وبالرسول وأطعنا ثم يتولى فريق منهم من بعد ذلك وما أولئك بالمؤمنين","އެއުރެން ބުނެތެވެ. ﷲއަށާއި، ރަސޫލާއަށް ތިމަންމެން އީމާން ވެއްޖައީމުއެވެ. އަދި ތިމަންމެން ކިޔަމަންވެއްޖައީމުއެވެ. ދެން އެއަށްފަހު، އޭގެތެރެއިން ބަޔަކުމީހުން ފުރަގަސްދީ، ހިނގައިދެތެވެ. އަދި އެއުރެން މުއުމިނުން ކަމުގައެއް ނުވެތެވެ.","",""],["","","","وإذا دعوا إلى الله ورسوله ليحكم بينهم إذا فريق منهم معرضون","އަދި އެއުރެންގެ މެދުގައި ހުކުމްކުރެއްވުމަށް، ﷲއާއި އެކަލާނގެ ރަސޫލާގެ އަރިހަށް އައުމަށް، އެއުރެންނަށް ގޮވައިލައްވައިފިނަމަ، އެހާރުން އެއުރެންގެ ތެރެއިން ބަޔަކު، އެނބުރި ފުރަގަސްދޭބަޔަކު ކަމުގައިވެއެވެ.","",""],["","","","وإن يكن لهم الحق يأتوا إليه مذعنين","އަދި ހައްގު ލިބެންވަނީ، އެއުރެންނަށް ކަމަށްވާނަމަ، ރުހުމާއެކު، ކިޔަމަންތެރިކަމުގައި، އެކަލޭގެފާނުގެ އަރިހަށް އެއުރެން އާދެތެވެ.","",""],["","","","أفي قلوبهم مرض أم ارتابوا أم يخافون أن يحيف الله عليهم ورسوله بل أولئك هم الظالمون","އެއުރެންގެ ހިތްތަކުގައި ބައްޔެއް ވަނީހެއްޔެވެ؟ ނުވަތަ އެއުރެން (އެކަލޭގެފާނުގެ ނަބީކަމާމެދު) ޝައްކުކުރީ ހެއްޔެވެ؟ ނުވަތަ ﷲއާއި، އެކަލާނގެ ރަސޫލާ، އެއުރެންނަށް ބޭއިންސާފު ކުރައްވައިފާނެކަމަށް، އެއުރެން ބިރުގަންނަނީ ހެއްޔެވެ؟ އަދި ކިއެއްތަ! އެއުރެންނީ، ހަމަ އަނިޔާވެރިންނެވެ.","",""],["","","","إنما كان قول المؤمنين إذا دعوا إلى الله ورسوله ليحكم بينهم أن يقولوا سمعنا وأطعنا وأولئك هم المفلحون","އެއުރެންގެ މެދުގައި، ހުކުމްކުރެއްވުމަށް ﷲއާއި، އެކަލާނގެ ރަސޫލާގެ އަރިހަށް އައުމަށް، އެއުރެންނަށް ގޮވައިލައްވައިފިހިނދަކު، މުއުމިނުންގެ ބަހެއްކަމުގައިވާކަން ކަށަވަރީ، ތިމަންމެން އަހައިފީމުއޭ، އަދި ތިމަންމެން ކިޔަމަންވެއްޖައީމުއޭ، އެއުރެން ބުނުމެވެ. އަދި ދިންނަވާނޭ މީހުންނަކީ، ހަމަ އެއުރެންނެވެ.","",""],["","","","ومن يطع الله ورسوله ويخش الله ويتقه فأولئك هم الفائزون","އަދި ﷲއާއި، އެކަލާނގެ ރަސޫލާއަށް ކިޔަމަންވެ، އަދި ﷲއަށް ބިރުވެތިވެ، އެކަލާނގެއަށް ތަގުވާވެރިވާމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ ހަމަ ނަސީބު ލިބިގެންވާ މީހުންނެވެ.","",""],["","","","وأقسموا بالله جهد أيمانهم لئن أمرتهم ليخرجن قل لا تقسموا طاعة معروفة إن الله خبير بما تعملون","އަދި ކަލޭގެފާނު، އެއުރެންނަށް (އެބަހީ: މުނާފިގުންނަށް) އަމުރުކުރައްވައިފިނަމަ، ހަމަކަށަވަރުން، އެއުރެން (ހަނގުރާމައަށް) ނުކުންނާނެކަމަށް އެއުރެންގެ އެންމެ ގަދަ ހުވައިން ﷲ ގަންދީ ހުވާކުރާނެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ހުވާނުކުރާށެވެ! (ބޭނުމީ) އެނގި ފާޅުވެގެންވާ ކިޔަމަންގަތުމެކެވެ. ހަމަކަށަވަރުން، ﷲއީ، ތިޔަބައިމީހުންކުރާ ޢަމަލުތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","قل أطيعوا الله وأطيعوا الرسول فإن تولوا فإنما عليه ما حمل وعليكم ما حملتم وإن تطيعوه تهتدوا وما على الرسول إلا البلاغ المبين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ﷲއަށް ކިޔަމަންވާށެވެ! އަދި ތިޔަބައިމީހުން ރަސޫލާއަށްވެސް ކިޔަމަންވާށެވެ! ފަހެ، އެއުރެން ފުރަގަސްދީ ހިނގައްޖެނަމަ، ފަހެ، އެކަލޭގެފާނުގެ މައްޗަށް އޮތްކަން ކަށަވަރީ އެކަލޭގެފާނާ މަތިކުރެއްވި ކަންތަކެވެ. (އެއީ ރަސޫލު ކަން އިއްވެވުމެވެ.) އަދި ތިޔަބައިމީހުންގެ މައްޗަށްއޮތީ ތިޔަބައިމީހުންނާ މަތިކުރެއްވި ކަންތަކެވެ. (އެއީ އީމާންވެ ކިޔަމަންގަތުމެވެ.) އަދި ތިޔަބައިމީހުން އެކަލޭގެފާނަށް ކިޔަމަންވާނަމަ ތިޔަބައިމީހުންނަށް ތެދުމަގު ލިބޭނެތެވެ. ބަޔާން ވެގެންވާ އިއްވެވުން މެނުވީ ރަސޫލާގެ މައްޗަކަށް ނުވެއެވެ.","",""],["","","","وعد الله الذين آمنوا منكم وعملوا الصالحات ليستخلفنهم في الأرض كما استخلف الذين من قبلهم وليمكنن لهم دينهم الذي ارتضى لهم وليبدلنهم من بعد خوفهم أمنا يعبدونني لا يشركون بي شيئا ومن كفر بعد ذلك فأولئك هم الفاسقون","ތިޔަބައިމީހުންގެ ތެރެއިން އީމާންވެ، ސާލިހު ޢަމަލުތައްކޮށް އުޅުނުމީހުންނަށް، އެއުރެންގެ ކުރިން އުޅުނު މީހުން ޚަލީފާވެރިކުރެއްވިފަދައިން، ހަމަކަށަވަރުން، އެއުރެން ބިމުގައި ޚަލީފާވެރިކުރައްވާނެ ކަމަށާއި، އެއުރެންނަށްޓަކައި އެކަލާނގެ ރުއްސެވި އެއުރެންގެ ދީން، ހަމަކަށަވަރުން، އެބައިމީހުންނަށްޓަކައި ތަމްކީނުކުރައްވާނެ ކަމަށާއި، އެއުރެންގެ ބިރުވެރިކަމަށްފަހު، ހަމަކަށަވަރުން، އަމާންކަމަކަށް އެއުރެން ބަދަލުކުރައްވާނެކަމަށް، ﷲ ވައުދުކުރައްވާފައިވެއެވެ. އެއުރެން ތިމަންރަސްކަލާނގެއަށް އެއްވެސް އެއްޗެއް ޝަރީކު ނުކޮށް، ތިމަންރަސްކަލާނގެއަށް އަޅުކަން ކުރެތެވެ. އެއަށްފަހު ކާފިރު ވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ، ހަމަ ފާސިގުންނެވެ.","",""],["","","","وأقيموا الصلاة وآتوا الزكاة وأطيعوا الرسول لعلكم ترحمون","ތިޔަބައިމީހުން ނަމާދު ގާއިމުކުރާށެވެ! އަދި ޒަކާތް ދޭށެވެ! އަދި ރަސޫލާއަށް ކިޔަމަންވާށެވެ! (އެއީ) ތިޔަބައިމީހުންނަށް ރަހުމަތް ލެއްވުމަށްޓަކައެވެ.","",""],["","","","لا تحسبن الذين كفروا معجزين في الأرض ومأواهم النار ولبئس المصير","ކާފިރުވި މީހުންނަށް، ބިމުގައި ﷲ ނުކުޅައްދައިލެވޭނެކަމަށް ހަމަކަށަވަރުން، ކަލޭގެފާނު ހީފުޅު ނުކުރައްވާހުށިކަމެވެ! އަދި އެއުރެން ތިބެނިވި ތަނަކީ ނަރަކައެވެ. ހަމަކަށަވަރުން، އެއީ ހާދަހާ ނުބައިވެގެންވާ ނިމިދިއުމެކެވެ.","",""],["","","","يا أيها الذين آمنوا ليستأذنكم الذين ملكت أيمانكم والذين لم يبلغوا الحلم منكم ثلاث مرات من قبل صلاة الفجر وحين تضعون ثيابكم من الظهيرة ومن بعد صلاة العشاء ثلاث عورات لكم ليس عليكم ولا عليهم جناح بعدهن طوافون عليكم بعضكم على بعض كذلك يبين الله لكم الآيات والله عليم حكيم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންނަށް މިލްކުވެގެންވާ އަޅުންނާއި، ތިޔަބައިމީހުންކުރެ ބާލިޣު ވުމުގެ އުމުރު އާހަމައަށް ނުފޯރާ ކުޑަކުދިންވެސް، ތިންވަގުތެއްގައި ތިޔަބައިމީހުންގެ ކިބައިން އިޒުނަ ލިބިގަންނަހުށިކަމެވެ! އެއީ ފަތިސްނަމާދުގެ ކުރިންނާއި، މެންދުރުވަގުތު ތިޔަބައިމީހުންގެ ފޭރާން ލުއިކޮށްގެންތިބޭ ވަގުތުގައްޔާއި، ޢިޝާ ނަމާދުގެ ފަހުންނެވެ. (އެއީ) ތިޔަބައިމީހުން ނިވައިވެތިބޭ ތިންވަގުތެކެވެ. އެވަގުތުތަކަށްފަހު، ތިޔަބައިމީހުންގެ މައްޗަކަށްވެސް، އަދި އެއުރެންގެ މައްޗަކަށްވެސް (ވަދެނުކުމެ އުޅުމުގައި) ކުށެއް ނެތެވެ. (އެއުރެންނީ) ތިޔަބައިމީހުންގެ އެއްބަޔަކު ތިބޭތަނަކަށް އަނެއްބަޔަކު ވަދެނުކުމެއުޅޭ ބަޔެކެވެ. އެފަދައިން ﷲ، ތިޔަބައިމީހުންނަށް އާޔަތްތައް ބަޔާން ކޮށްދެއްވަތެވެ. އަދި ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وإذا بلغ الأطفال منكم الحلم فليستأذنوا كما استأذن الذين من قبلهم كذلك يبين الله لكم آياته والله عليم حكيم","އަދި ތިޔަބައިމީހުންގެ ތެރެއިން ކުޑަކުދިން، ބާލިޣު ވުމުގެ އުމުރު އާހަމައަށް ފޯރައްޖެނަމަ، އެކުދިންގެ ކުރިން އިސްވެދިޔަމީހުން (ތިޔަބައިމީހުންގެ ކިބައިން) އިޒުނަ ލިބިގަތްފަދައިން، އެކުދިންވެސް އިޒުނަ ލިބިގަންނަހުށިކަމެވެ! އެފަދައިން ﷲ، އެކަލާނގެ އާޔަތްތައް ތިޔަބައިމީހުންނަށް ބަޔާން ކޮށްދެއްވަތެވެ. އަދި ﷲއީ މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","والقواعد من النساء اللاتي لا يرجون نكاحا فليس عليهن جناح أن يضعن ثيابهن غير متبرجات بزينة وأن يستعففن خير لهن والله سميع عليم","ކާވެންޏަކަށް އެދުންނުވާ، މުސްކުޅި އަންހެނުން، ޒީނަތްތެރިކަން ފާޅުނުކުރާގޮތުގައި، އެކަނބަލުންގެ ފޭރާން ލުއިކޮށްލުމަކުން، އެކަނބަލުންގެ މައްޗަކަށް ކުށެއް ނެތެވެ. (ނަމަވެސް) އެކަނބަލުން ޢިއްފަތް ތެރިވުން އެކަނބަލުންނަށް ހެޔޮކަން ބޮޑެވެ. ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ليس على الأعمى حرج ولا على الأعرج حرج ولا على المريض حرج ولا على أنفسكم أن تأكلوا من بيوتكم أو بيوت آبائكم أو بيوت أمهاتكم أو بيوت إخوانكم أو بيوت أخواتكم أو بيوت أعمامكم أو بيوت عماتكم أو بيوت أخوالكم أو بيوت خالاتكم أو ما ملكتم مفاتحه أو صديقكم ليس عليكم جناح أن تأكلوا جميعا أو أشتاتا فإذا دخلتم بيوتا فسلموا على أنفسكم تحية من عند الله مباركة طيبة كذلك يبين الله لكم الآيات لعلكم تعقلون","(އެކަކު އަނެކަކާއެކު ކައިބޮއި އުޅުމުގައި) ކަނުމީހާގެ މައްޗަކަށް ކުށެއް ނެތެވެ. އަދި ކޮރުމީހާގެ މައްޗަކަށްވެސް ކުށެއް ނެތެވެ. އަދި ބަލިމީހާގެ މައްޗަކަށްވެސް ކުށެއް ނެތްމެއެވެ. އަދި ތިޔަބައިމީހުންގެ ގޭގެއިން، ނުވަތަ ތިޔަބައިމީހުންގެ ބަފައިންގެ ގޭގެއިން، ނުވަތަ ތިޔަބައިމީހުންގެ މައިންގެ ގޭގެއިން، ނުވަތަ ތިޔަބައިމީހުންގެ އަޚުންގެ ގޭގެއިން ނުވަތަ ތިޔަބައިމީހުންގެ އުޚްތުންގެ ގޭގެއިން، ނުވަތަ ތިޔަބައިމީހުންގެ ބަފައިފުށުގެ ބޮޑުބޭބެއިންގެ ގޭގެއިން، ނުވަތަ ތިޔަބައިމީހުންގެ ބަފައިފުށުގެ ބޮޑުދައިތައިންގެ ގޭގެއިން، ނުވަތަ ތިޔަބައިމީހުންގެ މައިފުށުގެ ބޮޑުބޭބެއިންގެ ގޭގެއިން ނުވަތަ ތިޔަބައިމީހުންގެ މައިފުށުގެ ބޮޑުދައިތައިންގެ ގޭގެއިން، ނުވަތަ ތިޔަބައިމީހުންނަށް އެ ތަންތާނގެ ތަޅުދަނޑިތައް މިލްކުވެގެންވާ ގޭގެއިން، ނުވަތަ ތިޔަބައިމީހުންގެ ރަހުމަތް ތެރިއެއްގެ ގެއިން، ތިޔަބައިމީހުން ކައިއުޅުމަކުން، ތިޔަބައިމީހުންގެ ނަފްސުތަކުގެ މައްޗަކަށް ކުށެއް ނެތެވެ. އަދި ތިޔަބައިމީހުން އެންމެން އެކުގައި، ނުވަތަ ވަކިވަކިން ކައިބޮއި އުޅުމަކުންވެސް، ތިޔަބައިމީހުންގެ މައްޗަކަށް ކުށެއް ނެތެވެ. ފަހެ، ތިޔަބައިމީހުން ގޭގެއަށް ވަންނައިރު، ﷲގެ ހަޒުރަތު ންވާ ބަރަކާތް ތެރި ރަނގަޅު ސަލާމަކުން ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތަކަށް ތިޔަބައިމީހުން ސަލާމްކުރާށެވެ! އެފަދައިން ﷲ، ތިޔަބައިމީހުންނަށް އާޔަތްތައް ބަޔާން ކޮށްދެއްވަތެވެ. (އެއީ) ތިޔަބައިމީހުން ވިސްނުމަށްޓަކައެވެ.","",""],["","","","إنما المؤمنون الذين آمنوا بالله ورسوله وإذا كانوا معه على أمر جامع لم يذهبوا حتى يستأذنوه إن الذين يستأذنونك أولئك الذين يؤمنون بالله ورسوله فإذا استأذنوك لبعض شأنهم فأذن لمن شئت منهم واستغفر لهم الله إن الله غفور رحيم","މުއުމިނުން ވާކަން ކަށަވަރީ، ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް އީމާންވި މީހުން ކަމުގައެވެ. އަދި އެއްވުމަކަށްވާ މުހިންމު ކަމެއްގައި، އެކަލޭގެފާނުގެ އަރިހުގައި އެއުރެން ވެއްޖެނަމަ، އެކަލޭގެފާނުގެ އަރިހުން އިޒުނަ ލިބިއްޖައުމަންދާނދެން އެއުރެން ނުދެއެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ އަރިހުން އިޒުނަށް އެދޭމީހުން (ދަންނާށެވެ!) އެއުރެންނީ، ﷲއަށާއި އެކަލާނގެ ރަސޫލާއަށް އީމާންވާ މީހުންނެވެ. ފަހެ، އެއުރެންގެ ބައެއް ކަންތަކަށްޓަކައި ކަލޭގެފާނުގެ އަރިހުން އެއުރެން އިޒުނަށް އެދިއްޖެނަމަ، އެއުރެންގެ ތެރެއިން ކަލޭގެފާނު ގަސްދުކުރެއްވި މީހަކަށް އިޒުނަ ދެއްވާށެވެ! އަދި އެއުރެންނަށް ފާފަ ފުއްސެވުމަށް ﷲގެ ހަޒުރަތުން އެދިވަޑައިގަންނަވާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","لا تجعلوا دعاء الرسول بينكم كدعاء بعضكم بعضا قد يعلم الله الذين يتسللون منكم لواذا فليحذر الذين يخالفون عن أمره أن تصيبهم فتنة أو يصيبهم عذاب أليم","ތިޔަބައިމީހުންގެ އެއްބަޔަކު އަނެއްބަޔަކަށް ގޮވައިއުޅޭފަދައިން ތިޔަބައިމީހުންގެ މެދުގައި ރަސޫލާއަށް ގޮވައިނޫޅޭށެވެ! ތިޔަބައިމީހުންގެ ތެރެއިން (އިޛުނެއްނެތި) ފިލައިގެންދާ މީހުން ހަމަކަށަވަރުން، ﷲ ދެނެވޮޑިގެންވެތެވެ. ފަހެ، އެކަލާނގެ އަމުރު ފުޅާ ޚިލާފު ވާމީހުންނަށް ބަލާއެއް ނުވަތަ ވޭންދެނިވި އަޒާބެއް ޖެހިދާނެކަމަށް، އެއުރެން ބިރުވެތިވާހުށިކަމެވެ!","",""],["","","","ألا إن لله ما في السماوات والأرض قد يعلم ما أنتم عليه ويوم يرجعون إليه فينبئهم بما عملوا والله بكل شيء عليم","ދަންނާށެވެ! ހަމަކަށަވަރުން، އުޑުތަކާއި، ބިމުގައިވާހާ ތަކެތި މިލްކުވެގެންވަނީ، ﷲއަށެވެ. ތިޔަބައިމީހުން އެގޮތެއްގެ މަތީގައި ތިބިގޮތް ހަމަކަށަވަރުން، އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަދި އެކަލާނގެ ހަޒުރަތަށް އެއުރެން އެނބުރިދާ ދުވަސްވެސް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. ފަހެ، އެއުރެންކުރި ޢަމަލުތަކުގެ ވާހަކައިން އެކަލާނގެ އެއުރެންނަށް ޚަބަރު އަންގަވާނެތެވެ. ﷲއީ، ކޮންމެ ކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم تبارك الذي نزل الفرقان على عبده ليكون للعالمين نذيرا","އާލަމްތަކަށް އިންޒާރުކުރައްވާ ބޭކަލަކު ކަމުގައިވުމަށް، އެކަލާނގެ އަޅާއަށް ގުރްއާން ބާވައިލެއްވި ކަލާނގެ، މަތިވެރިވެވޮޑިގެންފިއެވެ.","",""],["","","","الذي له ملك السماوات والأرض ولم يتخذ ولدا ولم يكن له شريك في الملك وخلق كل شيء فقدره تقديرا","އެކަލާނގެއީ، އުޑުތަކާއި، ބިމުގެ ވެރިކަން އެކަލާނގެއަށް މަލަކަ ވެގެންވާ ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެ ދަރިކަލަކު ނުހިއްޕަވައެވެ. އަދި ވެރިކަމުގައި އެކަލާނގެއަށް އެއްވެސް ބައިވެރިޔަކު ނުވެއެވެ. އަދި އެކަލާނގެ ކޮންމެ އެއްޗެއް ހެއްދެވިއެވެ. ފަހެ، އެކަލާނގެ އެތަކެތި ވަރަށް ފުރިހަމަޔަށް މިންވަރު ކުރެއްވިއެވެ.","",""],["","","","واتخذوا من دونه آلهة لا يخلقون شيئا وهم يخلقون ولا يملكون لأنفسهم ضرا ولا نفعا ولا يملكون موتا ولا حياة ولا نشورا","އެއުރެން، އެކަލާނގެ ފިޔަވައި އެހެން އިލާހުންތަކެއް ހިފޫއެވެ. އެއްވެސް އެއްޗެއް ނެހެދޭ އިލާހު ންތަކެކެވެ. އަދި އެތަކެއްޗަކީ، ހައްދަވާފައިވާ ތަކެއްޗެވެ. އެތަކެތީގެ އަމިއްލަ ނަފްސުތަކަށް ގެއްލުމެއް ދިނުމެއްވެސް، އަދި މަންފާއެއް ކުރުމެއްވެސް އެތަކެއްޗަކަށް މިލްކުވެގެނެއް ނުވެތެވެ. އަދި މަރުހިފުމެއްވެސް، އަދި ދިރުވުމެއްވެސް، އަދި އަލުން ދިރުމަކަށް ފޮނުވުމެއްވެސް، އެތަކެއްޗަށް މިލްކުވެގެނެއް ނުވެތެވެ.","",""],["","","","وقال الذين كفروا إن هذا إلا إفك افتراه وأعانه عليه قوم آخرون فقد جاءوا ظلما وزورا","ކާފިރުވި މީހުން ބުނޫއެވެ. އެކަލޭގެފާނު (އަމިއްލަފުޅަށް) އުފައްދަވައިގެން އުޅުއްވާ ދޮގެއްކަމުގައި މެނުވީ، މި ގުރްއާން ނުވެއެވެ. އަދި އެކަމުގެމައްޗަށް އެހެން ބަޔަކު އެކަލޭގެފާނާ އެހީވޫއެވެ. ފަހެ، ހަމަކަށަވަރުން، އެއުރެން އެ ގެނައީ، އަނިޔާވެރިވުމެކެވެ. އަދި ބޮޑުވެގެންވާ ދޮގެކެވެ.","",""],["","","","وقالوا أساطير الأولين اكتتبها فهي تملى عليه بكرة وأصيلا","އަދި އެއުރެން ބުނޫއެވެ. (އެއީ) އެކަލޭގެފާނު މީހުންލައްވައި ލިޔުއްވާފައިވާ، އެވޭލާ މީހުން ދައްކައިއުޅުނު ފުލޯކު ވާހަކަތަކެކެވެ. ފަހެ، އެތަކެތި ހެނދުނާއި ހަވީރު، އެކަލޭގެފާނަށް ކިޔައިދެތެވެ.","",""],["","","","قل أنزله الذي يعلم السر في السماوات والأرض إنه كان غفورا رحيما","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެ ގުރްއާން ބާވައިލެއްވީ، އުޑުތަކާއި، ބިމުގައިވާ ސިއްރުތައް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. ހަމަކަށަވަރުން، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ކަލަކު ކަމުގައި، އެކަލާނގެ ވޮޑިގެންވެއެވެ.","",""],["","","","وقالوا مال هذا الرسول يأكل الطعام ويمشي في الأسواق لولا أنزل إليه ملك فيكون معه نذيرا","އަދި އެއުރެން ބުނޫއެވެ. މި ރަސޫލާއަށްވީ ކީއްހެއްޔެވެ؟ އެކަލޭގެފާނު ކާތަކެތި ފަރީއްކުޅުއްވަތެވެ. އަދި ބާޒާރުތަކުގައި ހިންގަވައި އުޅުއްވަތެވެ. ފަހެ، އެކަލޭގެފާނުގެ އަރިހުގައި އިންޒާރުކުރައްވައި އުޅުއްވުމަށް، އެކަލޭގެފާނުގެ އަރިހަށް މަލާއިކަތަކު ބާވައިނުލެއްވީ ކީއްވެގެން ހެއްޔެވެ؟","",""],["","","","أو يلقى إليه كنز أو تكون له جنة يأكل منها وقال الظالمون إن تتبعون إلا رجلا مسحورا","ނުވަތަ އެކަލޭގެފާނަށް ޚަޒާނާއެއް ބާވައިނުލެއްވީ، ނުވަތަ އެކަލޭގެފާނު އެތަނުން ފަރީއްކުޅުއްވައި އުޅުއްވުމަށް، އެކަލޭގެފާނަށް ބަގީޗާއެއް ނެތީ ކީއްވެގެން ހެއްޔެވެ؟ އަދި އަނިޔާވެރިން ބުނޫއެވެ. ޖާދޫޖެހި، ބުއްދި އޮޅިފައިވާ މީހަކަށް މެނުވީ ތިޔަބައިމީހުން ތަބައެއް ނުވަމުއެވެ.","",""],["","","","انظر كيف ضربوا لك الأمثال فضلوا فلا يستطيعون سبيلا","ކަލޭގެފާނާމެދު އެއުރެން މިސާލުޖެހީ، ކޮންފަދައަކުންކަން ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާށެވެ! ފަހެ، އެއުރެން މަގުފުރެދިއްޖައޫއެވެ. ފަހެ، މަގެއް ހޯދުމަކަށް އެއުރެންނަކަށް ކުޅަދާނަވެގެނެއް ނުވެތެވެ.","",""],["","","","تبارك الذي إن شاء جعل لك خيرا من ذلك جنات تجري من تحتها الأنهار ويجعل لك قصورا","އެކަލާނގެ އިރާދަކުރައްވައިފިނަމަ، އެއަށްވުރެ ހެޔޮގޮތް ކަލޭގެފާނަށް ލައްވައިދެއްވާ ރަސްކަލާނގެ މަތިވެރިވެވޮޑިގެންފިއެވެ. (އެއީ) އެތާނގެ ދަށުން ކޯރުތައް ހިނގައިހިނގާ ހުންނަ ސުވަރުގެތަކެވެ. އަދި އެކަލާނގެ (އެތާނގައި) ކަލޭގެފާނަށްޓަކައި ގަނޑުވަރުތައް ލައްވާނެތެވެ.","",""],["","","","بل كذبوا بالساعة وأعتدنا لمن كذب بالساعة سعيرا","އަދި ކިއެއްތަ! އެއުރެން ގިޔާމަތްގެ ވަގުތު ދޮގުކުޅައޫއެވެ. އަދި ގިޔާމަތްގެ ވަގުތު ދޮގުކުޅަމީހަކަށް، އަނދައަނދާ ހުންނަ ނަރަކަ ތިމަންރަސްކަލާނގެ ތައްޔާރުކުރެއްވީމެވެ.","",""],["","","","إذا رأتهم من مكان بعيد سمعوا لها تغيظا وزفيرا","ދުރުހިސާބަކުން އެ ނަރަކަޔަށް އެއުރެން ފެންނަހިނދު، ރުޅިއައިސް ކެކިއަރާ އަޑާއި، މާނޭވާގެ އަޑު، އެ ނަރަކައިން އެއުރެންނަށް އިވޭނެތެވެ.","",""],["","","","وإذا ألقوا منها مكانا ضيقا مقرنين دعوا هنالك ثبورا","އަދި އެއުރެންގެ އަތްތަކުގައި، ކަސްތޮޅު އަޅުއްވާފައިވާ ޙާލު، އެ ނަރަކައިގެ ތެރެއިން ދަތިތަނަކަށް އެއުރެން އެއްލަވާހިނދު، އެއުރެން އެތާނގައި ހަލާކުވުމަށްއެދި ގޮވާނެތެވެ.","",""],["","","","لا تدعوا اليوم ثبورا واحدا وادعوا ثبورا كثيرا","މިއަދު ތިޔަބައިމީހުން އެންމެ ހަލާކަކަށްއެދި ނުގޮވާށެވެ! އަދި އެތައް ހަލާކުތަކަކަށްއެދި ތިޔަބައިމީހުން ގޮވާށެވެ!","",""],["","","","قل أذلك خير أم جنة الخلد التي وعد المتقون كانت لهم جزاء ومصيرا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހެޔޮކަންބޮޑީ އެގޮތްހެއްޔެވެ؟ ނުވަތަ ތަގުވާވެރިންނަށް ވައުދުކުރައްވާފައިވާ، ދެމިތިބުމުގެ ސުވަރުގެ ހެއްޔެވެ؟ އެއުރެންނަށް ޖަޒާއެއްކަމުގައި އެ ސުވަރުގެ ވެއެވެ. އަދި އެންމެފަހުން ރުޖޫއަ ވަނިވި ތަނެއްކަމުގައިވެސް (އެތަން) ވޭމެއެވެ.","",""],["","","","لهم فيها ما يشاءون خالدين كان على ربك وعدا مسئولا","އެއުރެން އެދޭހާ ކަމެއް އެ ސުވަރުގޭގައި އެއުރެންނަށް ހުށްޓެވެ. ދެމިތިބެނިވި ގޮތުގައެވެ. ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން (އެއުރެންނަށް) ފުއްދަވާނޭ ވައުދެއް ކަމުގައި އެކަންތައް ވިއެވެ.","",""],["","","","ويوم يحشرهم وما يعبدون من دون الله فيقول أأنتم أضللتم عبادي هؤلاء أم هم ضلوا السبيل","އަދި ﷲ ފިޔަވައި އެއުރެން އަޅުކަންކުރާ ތަކެއްޗާއެކު، އެއުރެން މަހުޝަރަށް ފޮނުއްވާ ދުވަސް ހަނދުމަކުރާށެވެ! ފަހެ، އެކަލާނގެ ވަހީކުރައްވާނެތެވެ. ތިމަންރަސްކަލާނގެ މިތިބަ އަޅުން މަގުފުރެއްދީ، ތިޔަބައިމީހުން ހެއްޔެވެ؟ ނުވަތަ އެއުރެން (އަމިއްލައަށް) މަގުފުރެދުނީ ހެއްޔެވެ؟","",""],["","","","قالوا سبحانك ما كان ينبغي لنا أن نتخذ من دونك من أولياء ولكن متعتهم وآباءهم حتى نسوا الذكر وكانوا قوما بورا","އެއުރެން ދަންނަވާނެތެވެ. އިބަރަސްކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! އިބަރަސްކަލާނގެ ފިޔަވައި އެހެން އެހީތެރިފަރާތްތަކެއް ހިފުމަކީ، ތިމަންމެންނަށް އެކަށީގެންވާ ކަމެއްކަމުގައި ނުވެއެވެ. އެހެނެއްކަމަކު، އިބަރަސްކަލާނގެ އެއުރެންނަށާއި، އެއުރެންގެ ކާބަފައިންނަށް ފަސޭހަ ދިރިއުޅުމާއި، ނިއުމަތް ދެއްވީމުއެވެ. ވައުޒާއި ނަސޭހަތްގެ މަތިން އެއުރެން ހަނދާން ނައްތައިފުމަށް ދާނދެނެވެ. އަދި ގެއްލި ހަލާކުވި ބަޔަކުކަމުގައި، އެއުރެން ވޫއެވެ.","",""],["","","","فقد كذبوكم بما تقولون فما تستطيعون صرفا ولا نصرا ومن يظلم منكم نذقه عذابا كبيرا","ފަހެ، ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ބުނެއުޅުނު ބަސްތަކުން (އެބަހީ: އެއުރެންނަކީ، ތިޔަބައިމީހުންގެ އިލާހުން ކަމަށް ބުނެއުޅުނު ބަސްތަކުން) އެއުރެން (އެބަހީ: އެއަޅުކަންވެވުނު ފަރާތްތައް) ތިޔަބައިމީހުން ދޮގުކުރޫއެވެ. ފަހެ، އަޒާބު ދުރުކުރުމަކަށް، ނުވަތަ ނަސްރު ލިބިގަތުމަކަށް، ތިޔަބައިމީހުންނަކަށް ކުޅަދާނަވެގެނެއް ނުވެތެވެ. ތިޔަބައިމީހުންކުރެ އަނިޔާވެރިވާ މީހާ (ދަންނާށެވެ!) ބޮޑުވެގެންވާ އަޒާބުގެރަހަ، ތިމަންރަސްކަލާނގެ އެމީހަކަށް ދައްކަވާހުށީމެވެ.","",""],["","","","وما أرسلنا قبلك من المرسلين إلا إنهم ليأكلون الطعام ويمشون في الأسواق وجعلنا بعضكم لبعض فتنة أتصبرون وكان ربك بصيرا","ހަމަކަށަވަރުން، ކާތަކެތި ފަރީއްކުޅުއްވައި، ބާޒާރުތަކުގައި ހިންގަވައި އުޅުއްވާ ބޭކަލުން މެނުވީ، ކަލޭގެފާނުގެ ކުރިންވެސް ރަސޫލުންގެ ތެރެއިން އެއްވެސް ރަސޫލަކު ތިމަންރަސްކަލާނގެ ނުފޮނުއްވަމެވެ. އަދި ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން އެއްބަޔަކު އަނެއްބަޔަކަށް އިމްތިހާނެއްކަމުގައި ލެއްވީމެވެ. ތިޔަބައިމީހުން ކެތްކުރަމުހެއްޔެވެ؟ އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ މޮޅަށް ބައްލަވާވޮޑިގެންވާ ކަލަކުކަމުގައިވެއެވެ.","",""],["","","","وقال الذين لا يرجون لقاءنا لولا أنزل علينا الملائكة أو نرى ربنا لقد استكبروا في أنفسهم وعتوا عتوا كبيرا","ތިމަންރަސްކަލާނގެއާ ބައްދަލުވުމަށް ނޭދޭމީހުން ބުނޫއެވެ. ތިމަންމެންގެ މައްޗަށް މަލާއިކަތުން ބާވައިނުލެއްވީ، ނުވަތަ ތިމަންމެންގެ ވެރިރަސްކަލާނގެ ތިމަންމެންނަށް ނުފެންނަނީ ކީއްވެގެންހެއްޔެވެ؟ ހަމަކަށަވަރުން، އެއުރެންގެ ނަފްސު ތަކާމެދު އެއުރެން ބޮޑާވެގަތޫއެވެ. އަނިޔާވެރިކަމުގައި ބޮޑުވެގެންވާ ހައްދުފަހަނަޅައިދިޔުމަކުން އެއުރެން ހައްދުފަހަނަޅައިދިޔައޫއެވެ.","",""],["","","","يوم يرون الملائكة لا بشرى يومئذ للمجرمين ويقولون حجرا محجورا","އެއުރެން މަލާއިކަތުން ދެކޭ ދުވަސް ހަނދުމަކުރާށެވެ! އެދުވަހުން ކުށްވެރިންނަކަށް އުފާވެރިޚަބަރެއް ނެތެވެ. އަދި އެ މަލާއިކަތުން ވިދާޅުވާނެތެވެ. ހަރާމުން ޙަރާމެވެ. (އެބަހީ: ތިޔަބައިމީހުންގެ މައްޗަށް ސުވަރުގެއާއި، މަޣުފިރަތާއި، އުފާވެރި ޚަބަރު، ހަރާމް ވެގެންވެއެވެ.)","",""],["","","","وقدمنا إلى ما عملوا من عمل فجعلناه هباء منثورا","އަދި ޢަމަލުގެ ތެރެއިން އެއުރެންކުޅަ ކަންތަކަށް، ތިމަންރަސްކަލާނގެ ބައްލަވައި، އެ ޢަމަލުތައް ވަޔާބުރައިގެންދާ ކުނޑިފުއްތަކެއް ފަދައިން ލައްވާހުށީމެވެ.","",""],["","","","أصحاب الجنة يومئذ خير مستقرا وأحسن مقيلا","އެދުވަހުން ހަމަޖެހި ތިބޭތަނުގެ ގޮތުން، ސުވަރުގޭގެ އަހުލުވެރިން ހެޔޮކަންބޮޑެވެ. އަދި އަރާމުކުރަންތިބޭ ތަނުގެ ގޮތުންވެސް ރަނގަޅުކަން ބޮޑުމެއެވެ.","",""],["","","","ويوم تشقق السماء بالغمام ونزل الملائكة تنزيلا","ވިލާތަކާއެކު އުޑު ފަޅަފަޅައިގެންދާ ދުވަސް ހަނދުމަކުރާށެވެ! އަދި ގިނަ އަދަދަކަށް އެދުވަހު މަލާއިކަތުން ބާވައިލައްވާނެތެވެ.","",""],["","","","الملك يومئذ الحق للرحمن وكان يوما على الكافرين عسيرا","އެދުވަހު ހަގީގީވެރިކަންވަނީ، ރަޙްމާންވަންތަ ރަސްކަލާނގެއަށެވެ. އަދި ކާފިރުންގެ މައްޗަށް ދަތިކަން ބޮޑު ދުވަހެއްކަމުގައި އެދުވަސްވެއެވެ.","",""],["","","","ويوم يعض الظالم على يديه يقول يا ليتني اتخذت مع الرسول سبيلا","އަނިޔާވެރިޔާ އޭނާގެ ދެއަތުގައި ދަތްއަޅާ ދުވަސް ހަނދުމަކުރާށެވެ! އޭނާ (އެދުވަހުން) ބުނާނެތެވެ. އޭ ސަހަރޯއެވެ! ރަސޫލާގެ އަރިހުން މަގެއް ހިފައި، ބޭނުންކުޅަނަމަ، ތިމަންނާއަށް ކިހާ ރަނގަޅުވީސްހެއްޔެވެ؟","",""],["","","","يا ويلتى ليتني لم أتخذ فلانا خليلا","އޭ ހުރި ހަލާކެއްގެ ބޮޑުކަމާއެވެ! ސަހަރޯއެވެ! ތިމަން އެވެނި މީހަކު މިތުރަކު ކަމުގައި ނުހިފިނަމަ، ކިހާ ރަނގަޅުވީސްހެއްޔެވެ!","",""],["","","","لقد أضلني عن الذكر بعد إذ جاءني وكان الشيطان للإنسان خذولا","ހަމަކަށަވަރުން، ތިމަންނާއާހަމަޔަށް އެ ގުރްއާން އައުމަށްފަހު، އޭނާ ތިމަން އެއިން އެއްކިބާކޮށް މަގުފުރައްދައިފިއެވެ. އިންސާނާއަށް އޭނާ ދެރަކޮށް ނިކަމެތިކޮށްލާ އެއްޗެއްކަމުގައި ޝައިތާނާ ވެއެވެ.","",""],["","","","وقال الرسول يا رب إن قومي اتخذوا هذا القرآن مهجورا","ރަސޫލާ ވިދާޅުވިއެވެ. އޭ އަޅުގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، ތިމަންއަޅާގެ ގައުމުގެމީހުން، މި ގުރްއާނަކީ އެއްކިބާކޮށްލާފައިވާ އެއްޗެއްކަމުގައި ހަދައިފޫއެވެ.","",""],["","","","وكذلك جعلنا لكل نبي عدوا من المجرمين وكفى بربك هاديا ونصيرا","ހަމައެފަދައިން، ތިމަންރަސްކަލާނގެ ކޮންމެ ނަބިއްޔަކަށް ކުށްވެރިންގެ ތެރެއިން އަދުއްވަކު ލެއްވީމެވެ. ތެދުމަގު ދައްކަވާ ކަލަކު ކަމުގައްޔާއި، މޮޅަށް ނަސްރު ދެއްވާ ކަލަކު ކަމުގައި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ފުދެއެވެ.","",""],["","","","وقال الذين كفروا لولا نزل عليه القرآن جملة واحدة كذلك لنثبت به فؤادك ورتلناه ترتيلا","ކާފިރުވި މީހުން ބުނޫއެވެ. އެކަލޭގެފާނުގެ މައްޗަށް އެއްފަހަރާ ގުރްއާން ބާވައިނުލެއްވީ ކީއްވެގެންހެއްޔެވެ؟ އެފަދައިންނެވެ. (އެބަހީ: ތިމަންރަސްކަލާނގެ ގުރްއާން ބާވައިލެއްވީ އެފަދައިން ބައިބަޔަށެވެ.) އެއީ ތިމަންރަސްކަލާނގެ އެއިން ކަލޭގެފާނުގެ ހިތްޕުޅަށް ސާބިތުކަން ދެއްވުމަށްޓަކައެވެ. އަދި ތިމަންރަސްކަލާނގެ އެ ގުރްއާން ލަސްލަހުން ކިޔަވައިދެއްވުމަކުން ކިޔަވައިދެއްވީމެވެ.","",""],["","","","ولا يأتونك بمثل إلا جئناك بالحق وأحسن تفسيرا","އަދި އެއުރެންނަކަށް ކަލޭގެފާނާ އިދިކޮޅަށް އެއްވެސް މިސާލެއް ނުގެނެވޭނެތެވެ. އެހެނެއްކަމަކު، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ހައްގު ބަސްފުޅު ގެނެސްދެއްވައި، އެއަށްވުރެ ސާފު ބަޔާނަކުން ބަޔާންކޮށްދެއްވާހުށީމެވެ.","",""],["","","","الذين يحشرون على وجوههم إلى جهنم أولئك شر مكانا وأضل سبيلا","އެއުރެންގެ މޫނުވަތަށް ނަރަކަޔަށް އެއްކުރައްވާ މީހުން ދަންނާށެވެ! އެއުރެންނީ ތިބޭތަނުގެ ގޮތުން ނުބައިވެގެންވާ ބަޔެކެވެ. އަދި މަގުފުރެދުންވެސް ބޮޑުވެގެންވާ ބަޔެއްމެއެވެ.","",""],["","","","ولقد آتينا موسى الكتاب وجعلنا معه أخاه هارون وزيرا","ހަމަކަށަވަރުން، މޫސާގެފާނަށް ތިމަންރަސްކަލާނގެ ފޮތް ދެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނާއެކު، އެކަލޭގެފާނުގެ އަޚު، ހާރޫނުގެފާނު ވަޒީރަކު ކަމުގައި ލެއްވީމެވެ.","",""],["","","","فقلنا اذهبا إلى القوم الذين كذبوا بآياتنا فدمرناهم تدميرا","ފަހެ، ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވީމެވެ. ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުޅަމީހުންގެ ގާތަށް ތިޔަ ދެބޭކަލުން ވަޑައިގަންނަވާށެވެ! ފަހެ، ތިމަންރަސްކަލާނގެ އެއުރެން ހަލާކު ކުރައްވައި ނެތިކުރެއްވީމެވެ.","",""],["","","","وقوم نوح لما كذبوا الرسل أغرقناهم وجعلناهم للناس آية وأعتدنا للظالمين عذابا أليما","އަދި ނޫޙުގެފާނުގެ ގައުމުގެމީހުން، ރަސޫލުން ދޮގުކުޅަހިނދު، ތިމަންރަސްކަލާނގެ އެއުރެން ޣަރަގުކުރެއްވީމެވެ. އަދި މީސްތަކުންނަށް އިބްރަތެއްކަމުގައި ތިމަންރަސްކަލާނގެ އެއުރެން ލެއްވީމެވެ. އަދި އަނިޔާވެރިންނަށްޓަކައި، ވޭންދެނިވި އަޒާބު ތިމަންރަސްކަލާނގެ ތައްޔާރުކުރެއްވީމެވެ.","",""],["","","","وعادا وثمود وأصحاب الرس وقرونا بين ذلك كثيرا","އަދި ޢާދު ބާގައިމީހުންނާއި، ޘަމޫދު ބާގައިމީހުންނާއި، ރައްސުގެއަހުލުވެރިންނާއި، އެދެމެދުގައިވާ އެތައް ޖީލުތަކެއްވެސްމެއެވެ. (ނޯޓު: ރައްސުގެ އަހުލުވެރިންނީ، ނަޖުދު ކަރައިގެ ޔަމާމާއެވެ ކިޔާ ރަށުގައި އުޅުނު ބަޔެއްކަމަށް ވެއެވެ.)","",""],["","","","وكلا ضربنا له الأمثال وكلا تبرنا تتبيرا","އެއިން ކޮންމެ ބަޔަކަށްމެ، ތިމަންރަސްކަލާނގެ މިސާލުތައް ދައްކަވައި، އިންޒާރުކުރެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އެއިންކޮންމެ ބަޔަކުމެ، ހަލާކުކުރައްވައި، ނެތިކުރެއްވީމެވެ.","",""],["","","","ولقد أتوا على القرية التي أمطرت مطر السوء أفلم يكونوا يرونها بل كانوا لا يرجون نشورا","ހަމަކަށަވަރުން، ނުބައިކަމުގެ ވާރެއިން ވާރޭވެހުނު ރަށް (އެބަހީ: ލޫޠު ބާގައިމީހުން އުޅުނު ސަދޫމެވެ ކިޔާ ރަށް) ކަޑައްތުކޮށް އެއުރެން އައޫއެވެ. ފަހެ، އެއުރެން އެތަން ދެކޭކަމުގައި ނުވޭހެއްޔެވެ؟ އަދި ކިއެއްތަ! އަލުން ދިރުއްވުމަކަށް ފޮނުއްވާނެ ކަމާމެދު، ބިރުވެތިނުވާ ބަޔަކު ކަމުގައި އެއުރެންވޫއެވެ.","",""],["","","","وإذا رأوك إن يتخذونك إلا هزوا أهذا الذي بعث الله رسولا","އަދި އެއުރެން ކަލޭގެފާނު ދެކޭހިނދު، އެއުރެން ކަލޭގެފާނަށް ފުރައްސާރަ ނޫނީ ނުކުރެތެވެ. (އަދި ބުނެތެވެ.) ﷲ، ރަސޫލަކު ކަމުގައި ފޮނުއްވި ބޭކަލަކީ މިއީހެއްޔެވެ؟","",""],["","","","إن كاد ليضلنا عن آلهتنا لولا أن صبرنا عليها وسوف يعلمون حين يرون العذاب من أضل سبيلا","އެކަމުގެ މައްޗަށް ތިމަންމެން ކެތްނުކުޅަނަމަ، ތިމަންމެންގެ އިލާހު ންތައް ފިޔަވައި ހަމަކަށަވަރުން، އޭނާ ތިމަންމެން މަގުފުރެއްދުމާ ގާތްކުޅައީސްކަން ކަށަވަރެވެ. އަދި އެއުރެން އަޒާބު ދެކޭހިނދު، މަގުފުރެދުންބޮޑީ ކޮންބަޔެއްކަން އެއުރެންނަށް ނިކަންހުރެ އެނގޭނެތެވެ.","",""],["","","","أرأيت من اتخذ إلهه هواه أفأنت تكون عليه وكيلا","އެމީހެއްގެ އެދުންތައް އެއީ، އެމީހެއްގެ އިލާހުކަމުގައި ހެދިމީހާ، ކަލޭގެފާނު ދެކެވަޑައިގަތީމުތޯއެވެ؟ ފަހެ، އޭނާ ބަލަހައްޓާ ވަކީލަކު ކަމުގައި، ކަލޭގެފާނު ވާނެތޯއެވެ؟","",""],["","","","أم تحسب أن أكثرهم يسمعون أو يعقلون إن هم إلا كالأنعام بل هم أضل سبيلا","ނުވަތަ އޭގެތެރެއިން ގިނަމީހުން އަހާކަމަށް، ނުވަތަ ވިސްނާކަމަށް، ކަލޭގެފާނު ހީފުޅުކުރައްވަމުތޯއެވެ؟ ޖަނަވާރުތަކެއް ފަދައިން މެނުވީ، އެއުރެން ނުވެތެވެ. އަދި ކިއެއްތަ! އެއަށްވުރެވެސް އެއުރެން މަގުފުރެދުން ބޮޑެވެ.","",""],["","","","ألم تر إلى ربك كيف مد الظل ولو شاء لجعله ساكنا ثم جعلنا الشمس عليه دليلا","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، ހިޔަނި ފަތުރުއްވާފައިވަނީ، ކޮންފަދައަކުންކަން ކަލޭގެފާނު ދެކެވަޑައި ނުގަންނަވަމުތޯއެވެ؟ އަދި އެކަލާނގެ އިރާދަކުރެއްވިނަމަ، ހިމޭންވެހުންނަ އެއްޗެއްކަމުގައި، އެ ހިޔަނި ލައްވައިފީހެވެ. ދެން އެ ހިޔަނީގެ މައްޗަށް، ދަލީލެއްކަމުގައި ތިމަންރަސްކަލާނގެ އެ، އިރު ލެއްވީމެވެ.","",""],["","","","ثم قبضناه إلينا قبضا يسيرا","ދެން ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް މަޑުމަޑުން ހިއްޕަވާ ހިއްޕެވުމަކުން، އެ ހިޔަނި ހިއްޕަވައި ނެތިކުރައްވަމެވެ.","",""],["","","","وهو الذي جعل لكم الليل لباسا والنوم سباتا وجعل النهار نشورا","އެކަލާނގެއީ، ރޭގަނޑު ނިވަލެއްކަމުގައި، އަދި ނިދުމަކީ އަރާމެއްކަމުގައި ލައްވައި، އަދި ދުވާލަކީ، ދިރިއުޅުން ހޯދުމަށް އުޅޭވަގުތެއްކަމުގައި ލެއްވި ރަސްކަލާނގެއެވެ.","",""],["","","","وهو الذي أرسل الرياح بشرا بين يدي رحمته وأنزلنا من السماء ماء طهورا","އަދި އެކަލާނގެ ރަހުމަތްގެ ކުރިޔަށް (އެބަހީ: ވާރޭގެ ކުރިޔަށް) އުފާވެރި ޚަބަރެއްގެގޮތުގައި، ވައިރޯޅި ފޮނުއްވީވެސް އެކަލާނގެއެވެ. އަދި ތާހިރުކުރަނިވި ފެން ތިމަންރަސްކަލާނގެ އުޑުން ބާވައިލެއްވީމެވެ.","",""],["","","","لنحيي به بلدة ميتا ونسقيه مما خلقنا أنعاما وأناسي كثيرا","(އެއީ) މަރުވެފައިވާ ރަށެއް، އެ ފެނުން އަލުން ދިރުއްވުމަށާއި، އަދި ތިމަންރަސްކަލާނގެ ހައްދަވާފައިވާ ތަކެތީގެތެރެއިން ޖަނަވާރުތަކަށާއި، ގިނަ އިންސާނުންނަށް އެ ފެން ބޯންދެއްވުމަށެވެ.","",""],["","","","ولقد صرفناه بينهم ليذكروا فأبى أكثر الناس إلا كفورا","އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެ ފެން، އެއުރެންގެ މެދުގައި، އެއްތަނުން އަނެއްތަނަށް ބަދަލުކުރެއްވީމެވެ. އެއުރެން އެކަން ހަނދުމަކުޅައުމަށްޓަކައެވެ. ފަހެ، މީސްތަކުންކުރެ ގިނަމީހުން، ދެކޮޅުވެރިވެ، ކާފިރު ވުން މެނުވީ ގަބޫލެއް ނުކުރޫއެވެ.","",""],["","","","ولو شئنا لبعثنا في كل قرية نذيرا","އަދި ތިމަންރަސްކަލާނގެ އިރާދަކުރެއްވިނަމަ، ކޮންމެ ރަށަކަށް އިންޒާރުކުރައްވާ ބޭކަލަކު ތިމަންރަސްކަލާނގެ ފޮނުއްވީމުހެވެ.","",""],["","","","فلا تطع الكافرين وجاهدهم به جهادا كبيرا","ފަހެ، ކާފިރުންނަށް ކަލޭގެފާނު ކިޔަމަންވެވަޑައި ނުގަންނަވާށެވެ! އަދި އެ ގުރްއާނުން ބޮޑުވެގެންވާ ޖިހާދަކުން ކަލޭގެފާނު އެއުރެންނާ ޖިހާދުކުރައްވާށެވެ!","",""],["","","","وهو الذي مرج البحرين هذا عذب فرات وهذا ملح أجاج وجعل بينهما برزخا وحجرا محجورا","އަދި އެކަލާނގެއީ، ދެ ކަނޑު އެއްކުރެއްވި (އެބަހީ: ކޯރުފެނާއި ކަނޑުގެ ލޮނުގަނޑު އެކުއެކުގައި ހިނގާގޮތަށްލެއްވި) ރަސްކަލާނގެއެވެ. މިއީ މީރުކަންބޮޑު މީރު ފެނެވެ. އަދި މިއީ ލޮނުކަން ގަދަ ލޮނު ފެނެވެ. އަދި އެކަލާނގެ އެ ދެ ކަނޑު ދެމެދުގައި، ހުރަހެއްލައްވައި، އަދި އެ ދެމެދު މަނާކުރަނިވި ފަރުދާއެއް ލެއްވިއެވެ.","",""],["","","","وهو الذي خلق من الماء بشرا فجعله نسبا وصهرا وكان ربك قديرا","އަދި އެކަލާނގެއީ ފެނުން (އެބަހީ: މަނިފޮދަކުން) އިންސާނާ ހެއްދެވި ރަސްކަލާނގެއެވެ. ފަހެ، އެކަލާނގެ އެ އިންސާނާގައި، ނަސަބާއި، ޅިޔަން ފަހަރިކަމުގެ ގުޅުން ލެއްވިއެވެ. އަދި ކުޅަދުންވަންތަ ކަލަކު ކަމުގައި، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ވޮޑިގެންވެއެވެ.","",""],["","","","ويعبدون من دون الله ما لا ينفعهم ولا يضرهم وكان الكافر على ربه ظهيرا","އެއުރެން ﷲ ފިޔަވައި އަޅުކަންކުރަނީ، އެއުރެންނަށް މަންފާއެއް ނުކުރާ، އަދި އެއުރެންނަށް ގެއްލުމެއްވެސް ނުދެވޭ ތަކެއްޗަށެވެ. ކާފިރު ވިމީހާ، އޭނާގެ ވެރިރަސްކަލާނގެއާ ދެކޮޅުހެދުމަށް، އެހީތެރިޔަކު ކަމުގައިވެއެވެ.","",""],["","","","وما أرسلناك إلا مبشرا ونذيرا","އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު ކަމުގައްޔާއި، އަދި އިންޒާރުކުރައްވާ ބޭކަލަކު ކަމުގައިމެނުވީ، ތިމަންރަސްކަލާނގެ ކަލާގެފާނު ނުފޮނުއްވަމެވެ.","",""],["","","","قل ما أسألكم عليه من أجر إلا من شاء أن يتخذ إلى ربه سبيلا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަމުގެ މައްޗަށް (އެބަހީ: ރަސޫލު ކަން އިއްވެވުމުގެ މައްޗަށް) ތިމަންކަލޭގެފާނު އެއްވެސް އުޖޫރައެއް ތިޔަބައިމީހުންގެ ކިބަޔަކުން ނޭދެމެވެ. އެހެނެއްކަމަކު، އެމީހެއްގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް މަގެއްހިފުމަށް އެދޭމީހާ، އެފަދަ މަގެއް ހޯދައިފާހުށިކަމެވެ!","",""],["","","","وتوكل على الحي الذي لا يموت وسبح بحمده وكفى به بذنوب عباده خبيرا","އަދި އަވަހާރަވުމެއްނުވާ، ދިރިދެމިވޮޑިގެންވާ ރަސްކަލާނގެއަށް ކަލޭގެފާނު ވަކީލުކުރައްވާށެވެ! އަދި އެކަލާނގެއަށް ހަމްދާއެކު، ތަސްބީހަ ވިދާޅުވާށެވެ! އެކަލާނގެ އަޅުތަކުންގެ ފާފަތަކުގެ ޚަބަރު މޮޅަށް ދެނެވޮޑިގެންވާ ކަލަކު ކަމުގައި އެކަލާނގެ ފުދެއެވެ.","",""],["","","","الذي خلق السماوات والأرض وما بينهما في ستة أيام ثم استوى على العرش الرحمن فاسأل به خبيرا","އެކަލާނގެއީ، އުޑުތަކާއި، ބިމާއި، އެދެމެދުގައިވާހާ އެއްޗެއް، ހަ ދުވަހުގެ ތެރޭގައި ހެއްދެވި ރަސްކަލާނގެއެވެ. ދެން ޢަރްޝުގެ މައްޗަށް އެކަލާނގެ އިސްތިވާވެ ވޮޑިގަތެވެ. އެކަލާނގެއީ، ރަޙްމާންވަންތަ ރަސްކަލާނގެއެވެ. ފަހެ، އެކަލާނގެއާމެދު މޮޅަށް ޚަބަރު ދަންނަ ފަރާތަކާ ކަލޭގެފާނު ސުވާލުކުރައްވާށެވެ!","",""],["","","","وإذا قيل لهم اسجدوا للرحمن قالوا وما الرحمن أنسجد لما تأمرنا وزادهم نفورا","އަދި ރަޙްމާންވަންތަ ރަސްކަލާނގެއަށް ތިޔަބައިމީހުން ސަޖިދަކުރާށޭ އެއުރެންނަށް ވިދާޅުވިހިނދު، އެއުރެން ބުނޫއެވެ. ރަޙްމާންވަންތަ ރަސްކަލާނގެއަކީ ކޮންއެއްޗެއްހޭ؟ ކަލޭގެފާނު ތިމަންމެންނަށް އަމުރުކުރައްވާ އެއްޗަކަށް ތިމަންމެން ސަޖިދަކުރާނެހެއްޔެވެ؟ އަދި އެއުރެންގެ ނަފުރަތުދިޔައީ އިތުރުވެގެންނެވެ.","",""],["","","","تبارك الذي جعل في السماء بروجا وجعل فيها سراجا وقمرا منيرا","އުޑުގައި ބުރުޖު ތަކެއް ލައްވައި، އަދި އެތާނގައި ވޮށަކާއި، އަލިކުރާ ހަނދެއްލެއްވި ރަސްކަލާނގެ މަތިވެރިވެވޮޑިގެންފިއެވެ.","",""],["","","","وهو الذي جعل الليل والنهار خلفة لمن أراد أن يذكر أو أراد شكورا","އަދި އެކަލާނގެއީ، ރެޔާއި ދުވާލު އެކައްޗަކަށްފަހު، އަނެކައްޗެއް އަންނަގޮތުގައި ލެއްވި ރަސްކަލާނގެއެވެ. އެއީ ހަނދުމަކުރުމަށް އެދޭމީހަކަށް، ނުވަތަ ޝުކުރުވެރިވުމަށް އެދޭމީހަކަށްޓަކައެވެ.","",""],["","","","وعباد الرحمن الذين يمشون على الأرض هونا وإذا خاطبهم الجاهلون قالوا سلاما","ރަޙްމާންވަންތަ ރަސްކަލާނގެ އަޅުންނީ، މަޑުމައިތިރިކަމާއެކު ބިމުގައި ހިނގާ އުޅޭމީހުންނެވެ. އަދި އެއުރެންނާ ޖާހިލުން މުޚާޠަބު ކޮށް ވާހަކަދައްކައިފި ހިނދަކު، އެއުރެން ސަލާމް އޭ ބުނެތެވެ.","",""],["","","","والذين يبيتون لربهم سجدا وقياما","އަދި އެއުރެންނީ، އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް އަޅުކަން ކުޅައުމަށް، ސަޖިދަކުރުމުގައްޔާއި، ގިޔާމަށްތިބުމުގައި، ރޭގަނޑުގެ ވަގުތު ހޭދަކުރާ މީހުންނެވެ.","",""],["","","","والذين يقولون ربنا اصرف عنا عذاب جهنم إن عذابها كان غراما","އަދި އެއުރެންނީ ދަންނަވާ މީހުންނެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ނަރަކައިގެ އަޒާބު، އަޅަމެންގެކިބައިން ދުރުކުރައްވައިފާނދޭވެ! ހަމަކަށަވަރުން، އެތާނގެ އަޒާބަކީ، ވަކިނުވެ ދެމިހުންނަ ކަމެކެވެ.","",""],["","","","إنها ساءت مستقرا ومقاما","ހަމަކަށަވަރުން، ހަމަޖެހިތިބޭ ތަނެއްގެ ގޮތުންނާއި، ގާއިމު ވެތިބޭ ވަޒަނެއްގެ ގޮތުން އެ ނަރަކަ ހާދަހާ ނުބައިވެގެންވެއެވެ.","",""],["","","","والذين إذا أنفقوا لم يسرفوا ولم يقتروا وكان بين ذلك قواما","އަދި އެއުރެންނީ، އެއުރެން ހޭދައެއް ކޮށްފިނަމަ އިސްރާފު ނުކުރާ، އަދި މުށްބާރުވެސް ނުކުރާ، އަދި އެދެމެދުގައި މެދުމިންވެ ތިބޭމީހުންނެވެ.","",""],["","","","والذين لا يدعون مع الله إلها آخر ولا يقتلون النفس التي حرم الله إلا بالحق ولا يزنون ومن يفعل ذلك يلق أثاما","އެއުރެންނީ ﷲއާއެކު އެހެން އިލާހަކަށް ގޮވައި ނަހަދާމީހުންނެވެ. އަދި ﷲ، ހުރުމަތް ތެރި ކުރައްވާފައިވާ ނަފްސެއް، ހައްގު ގޮތުންނޫނީ، ނުމަރާ މީހުންނެވެ. އަދި ޒިނޭނުކުރާ މީހުންނެވެ. އެއިން ކަމެއްކޮށްފިމީހާ (އެކަމުގެ) އުގޫބާތާ ބައްދަލުކުރާނެތެވެ.","",""],["","","","يضاعف له العذاب يوم القيامة ويخلد فيه مهانا","އެމީހަކަށް ގިޔާމަތް ދުވަހުން އަޒާބު ގިނަގުނަކުރައްވާހުށްޓެވެ. އަދި އިހާނެތިކަން ލިބިގެންވާ ޙާލު އެ އަޒާބުގެ ތެރޭގައި، އެމީހަކު ދެމިހުންނާނެތެވެ.","",""],["","","","إلا من تاب وآمن وعمل عملا صالحا فأولئك يبدل الله سيئاتهم حسنات وكان الله غفورا رحيما","ތައުބާވެ، އީމާންވެ، ގިނަގިނައިން ސާލިހު ޢަމަލުކުޅަމީހަކު މެނުވީއެވެ. ފަހެ، އެއުރެންނާމެދު (ދަންނާށެވެ!) ﷲ، އެއުރެންގެ ނުބައިކަންތައް، ހެޔޮކަންތަކަށް ބަދަލުކުރައްވާނެތެވެ. ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","ومن تاب وعمل صالحا فإنه يتوب إلى الله متابا","އަދި ތައުބާވެ ސާލިހު ޢަމަލު ކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އެމީހާއީ ގިނަގިނައިން ﷲއަށް ތައުބާވާ މީހެކެވެ.","",""],["","","","والذين لا يشهدون الزور وإذا مروا باللغو مروا كراما","އަދި އެއުރެންނީ ދޮގުހެކިނުދޭ މީހުންނެވެ. އަދި ބޭކާރު ބަސްތަކާއި ކަންތައް ދިމާވާހިނދު، މާތްމީހުންގެ ގޮތުގައި ފަހަނަޅައިދާ މީހުންނެވެ.","",""],["","","","والذين إذا ذكروا بآيات ربهم لم يخروا عليها صما وعميانا","އަދި އެއުރެންނީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ އާޔަތްތައް ހަނދާންކޮށްދޭހިނދު ބީރު ކަނު ބައެއްގެ ގޮތުގައި، އެ އާޔަތްތަކުގެ މައްޗަށް ވެއްޓި ނުގަންނަ މީހުންނެވެ.","",""],["","","","والذين يقولون ربنا هب لنا من أزواجنا وذرياتنا قرة أعين واجعلنا للمتقين إماما","އަދި އެއީ ބުނާމީހުންނެވެ. އަޅަމެންގެ ވެރިރަސްކަލާނކޮ! އަޅަމެންގެ އަނބިންގެ ކިބައިންނާއި، އަޅަމެންގެ ދަރިންގެ ކިބައިން، ލޮލަށް ފިނިކަން ލިބުމެއް އަޅަމެންނަށް ދެއްވާނދޭވެ! އަދި ތަގުވާވެރިންނަށް އިމާމުންކަމުގައި އަޅަމެން ލައްވާނދޭވެ!","",""],["","","","أولئك يجزون الغرفة بما صبروا ويلقون فيها تحية وسلاما","އެއުރެން ކެތްތެރިވީކަމަށްޓަކައި، ސުވަރުގޭގެ މަތިވެރި ދަރަޖަ އެއުރެންނަށް ޖަޒާއެއްގެގޮތުން ދެއްވާހުށްޓެވެ. އަދި އެތާނގައި، އެއުރެންނާ ބައްދަލުވާނީ، ތަޙިއްޔަތާއި، ސަލާމުންނެވެ.","",""],["","","","خالدين فيها حسنت مستقرا ومقاما","އެ ސުވަރުގޭގައި ދެމިތިބެނިވި ގޮތުގައެވެ. ހަމަޖެހިތިބޭ ތަނެއްގެ ގޮތުންނާއި، ގާއިމުވެ ތިބޭ ވަޒަނެއްގެގޮތުން އެތަން ރަނގަޅުކަމާއެވެ!","",""],["","","","قل ما يعبأ بكم ربي لولا دعاؤكم فقد كذبتم فسوف يكون لزاما","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންގެ ދުއާކުރުން ނުވާނަމަ، ތިމަންގެ ވެރިރަސްކަލާނގެ، ތިޔަބައިމީހުންނާމެދު ފަރުވާލެއް ނުބަހައްޓަވާނެތެވެ. ފަހެ، ހަމަކަށަވަރުން، ތިޔަބައިމީހުން (ހައްގު) ދޮގުކުޅައީމުއެވެ. ފަހެ، ނިކަންހުރެ އެކަމުގެ އަޒާބު، ތިޔަބައިމީހުންނަށް ލާޒިމްވެ ހުންނަހުށްޓެވެ.","",""],["","","","بسم الله الرحمن الرحيم طسم","ط س م (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","تلك آيات الكتاب المبين","މިއީ (ކަންތައްތައް) ބަޔާން ވެގެންވާ ފޮތުގެ (އެބަހީ: ގުރްއާންގެ) އާޔަތް ތަކެވެ.","",""],["","","","لعلك باخع نفسك ألا يكونوا مؤمنين","އެއުރެން މުއުމިނުން ކަމުގައި ނުވުމުން (އެކަމުގެ ހިތާމައިގައި) ކަލޭގެފާނުގެ ނަފްސު ހަލާކުކޮށްލައްވަނީތޯއެވެ. (އެބަހީ: އެހެން ނަހައްދަވާށެވެ!)","",""],["","","","إن نشأ ننزل عليهم من السماء آية فظلت أعناقهم لها خاضعين","ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާނަމަ، އެއުރެންގެ މައްޗަށް އުޑުން މުއުޖިޒާއެއް ބާވައިލައްވައިފީމުހެވެ. ފަހެ، އޭރުން އެއުރެންގެ ކަނދުރާތައް އެއަށް ކިޔަމަންވެ، މަޑުމައިތިރިވާނެތެވެ.","",""],["","","","وما يأتيهم من ذكر من الرحمن محدث إلا كانوا عنه معرضين","ރަޙްމާންވަންތަ ރަސްކަލާނގެ ހަޒުރަތުން އެމީހުންގެ ގާތަށް އަންނަ ކޮންމެ އައު އާޔަތަކަށް ފުރަގަސްދޭބަޔަކު ކަމުގައި މެނުވީ، އެއުރެން ނުވެތެވެ.","",""],["","","","فقد كذبوا فسيأتيهم أنباء ما كانوا به يستهزئون","ފަހެ، ހަމަކަށަވަރުން، އެއުރެން (އެތަކެތި) ދޮގުކުރޫއެވެ. ފަހެ، އެއުރެން އެކަންތަކަށް ފުރައްސާރަކޮށްއުޅުނު ކަންތަކުގެ ޚަބަރުތައް، ނިކަންހުރެ އެއުރެންގެ ގާތަށް އަންނަހުށްޓެވެ.","",""],["","","","أولم يروا إلى الأرض كم أنبتنا فيها من كل زوج كريم","ބިމުގެ (އަޖާއިބު) ކަންތައްތަކަށް އެއުރެން ނުބަލަނީހެއްޔެވެ؟ އެ ބިމުގައި މަންފާގިނަ ރަނގަޅު ހުރިހާ ބާވަތަކުން ތިމަންރަސްކަލާނގެ ކިހާގިނަ ގަސްތަކެއް ފެޅުއްވީން ހެއްޔެވެ؟","",""],["","","","إن في ذلك لآية وما كان أكثرهم مؤمنين","ހަމަކަށަވަރުން، އެކަންތަކުގައި (ﷲގެ ކުޅަދުންވަންތަކަމުގެ) ހެތްކެއް ވާކަން ކަށަވަރެވެ. އަދި އެއުރެންކުރެ ގިނަމީހުން އީމާންވާ ބަޔަކު ކަމުގައި ނުވެތެވެ.","",""],["","","","وإن ربك لهو العزيز الرحيم","އަދި ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ޢަޒީޒުވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","وإذ نادى ربك موسى أن ائت القوم الظالمين","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ މޫސާގެފާނަށް ނިދާ އިއްވެވިހިނދު ހަނދުމަކުރައްވާށެވެ! އަނިޔާވެރި ގައުމުގެމީހުންގެ ގާތަށް ކަލޭގެފާނު (ރަސޫލުކަމާއިގެން) ވަޑައިގަންނަވާށެވެ!","",""],["","","","قوم فرعون ألا يتقون","އެއީ ފިރްޢައުނުގެ ގައުމުގެމީހުންނެވެ. އެއުރެން ﷲއަށް ބިރުވެތި ނުވަނީހެއްޔެވެ؟","",""],["","","","قال رب إني أخاف أن يكذبون","އެކަލޭގެފާނު (އެބަހީ: މޫސާގެފާނު) ދެންނެވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! އެއުރެން ތިމަންކަލޭގެފާނު ދޮގުކޮށްފާނެކަމަށް ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނު ބިރުފުޅުގަނެތެވެ.","",""],["","","","ويضيق صدري ولا ينطلق لساني فأرسل إلى هارون","އަދި (އެއުރެން ތިމަންކަލޭގެފާނު ދޮގުކޮށްފާނެކަމަށް) ތިމަންކަލޭގެފާނުގެ ހިތްޕުޅު ދަތިވެއެވެ. އަދި (ތިމަންކަލޭގެފާނު އެދިވަޑައިގަންނަވާފަދަ ފަސޭހަކަމާއެކު) ތިމަންކަލޭގެފާނުގެ ދޫފުޅެއް ނުހިނގައެވެ. ފަހެ، (ތިމަންކަލޭގެފާނަށް ވާގިވެރިވުމަށް) ހާރޫނުގެފާނުގެ އަރިހަށް (ވަހީއާއިގެން ޖިބްރީލުގެފާނު) ފޮނުއްވައި ދެއްވާށެވެ!","",""],["","","","ولهم علي ذنب فأخاف أن يقتلون","އެއުރެންނާ ބެހޭގޮތުން، ތިމަންކަލޭގެފާނުގެ މައްޗަށް ކުށެއްވެސް އެބައޮތެވެ. ފަހެ، އެއުރެން ތިމަންކަލޭގެފާނު ގަތުލު ކޮށްފާނެކަމަށް ތިމަންކަލޭގެފާނު ބިރުފުޅު ގަނެތެވެ.","",""],["","","","قال كلا فاذهبا بآياتنا إنا معكم مستمعون","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ހަމަހިލާ އެހެންނަކުން ނުވާނެތެވެ. ފަހެ، ތިޔަދެބޭކަލުން ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާއިގެން ވަޑައިގަންނަވާށެވެ! ހަމަކަށަވަރުން، ތިޔަދެބޭކަލުންނާއެކު، ތިމަންރަސްކަލާނގެ އައްސަވާވޮޑިގެންވަމެވެ.","",""],["","","","فأتيا فرعون فقولا إنا رسول رب العالمين","ފަހެ، ތިޔަދެބޭކަލުން ފިރްޢައުނުގެގާތަށް ވަޑައިގެން ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ތިމަންމެންނީ އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ފޮނުއްވި ރަސޫލުންނެވެ.","",""],["","","","أن أرسل معنا بني إسرائيل","އިސްރާއީލުގެދަރިން (ދޫކޮށްލައި) ތިމަންބޭކަލުންނާއެކު ފޮނުވާށެވެ!","",""],["","","","قال ألم نربك فينا وليدا ولبثت فينا من عمرك سنين","އޭނާ (އެބަހީ: ފިރްޢައުނު، މޫސާގެފާނަށް) ދެންނެވިއެވެ. ކަލޭގެފާނު އުފަންވީއްސުރެން ފެށިގެން އަހުރެމެންގެ ތެރޭގައި ކަލޭގެފާނު ބަލައިބޮޑުކުރީ އަހުރެމެން ނޫންހެއްޔެވެ؟ އަދި ކަލޭގެފާނުގެ އުމުރުފުޅުން އެތައް އަހަރެއްވަންދެން އަހުރެމެންގެ ތެރޭގައި ކަލޭގެފާނު ހުންނެވީމުއެވެ.","",""],["","","","وفعلت فعلتك التي فعلت وأنت من الكافرين","އަދި ކަލޭގެފާނު (ތިމަން ކޮށްދިން ހެޔޮކަންތަކަށް) ދެކޮޅުވެރިވާ ޙާލު، ކަލޭގެފާނު އެ ކުރެއްވިކަމެއް ކުރެއްވީމުއެވެ.","",""],["","","","قال فعلتها إذا وأنا من الضالين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އެހެންވިއްޔާ ތިމަންކަލޭގެފާނަށް އެކަންތައް އޭރު އެ ކުރެއްވުނީ، މަގު ގެއްލިފައިވާ މީހުންގެ ތެރެއިންވާ ޙާލު ގައެވެ.","",""],["","","","ففررت منكم لما خفتكم فوهب لي ربي حكما وجعلني من المرسلين","ފަހެ، ތިޔަބައިމީހުން ދެކެ ތިމަންކަލޭގެފާނު ބިރުފުޅުގަތްހިނދު، ތިޔަބައިމީހުންނަށް ފިއްލަވައިގެން (މަދްޔަނަށް) ވަޑައިގަތީމެވެ. ފަހެ، ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، ތިމަންކަލޭގެފާނަށް ހިކުމަތާއި، ވިސްނުން ދެއްވިއެވެ. އަދި ރަސޫލުންގެ ތެރެއިން ތިމަންކަލޭގެފާނު ލެއްވިއެވެ.","",""],["","","","وتلك نعمة تمنها علي أن عبدت بني إسرائيل","އަދި ތިމަންކަލޭގެފާނަށް ކަލޭ ދިން ނިއުމަތެއްކަމުގައި ތިޔަ ކަލަގޮވާ ނިއުމަތަކީ، ކަލޭ އިސްރާއީލުގެދަރިން އަޅުވެތިކޮށްލިކަމެވެ. (އެބަހީ: އަހުރެން އަޅުވެތިނުކޮށް ދޫކޮށްލިނަމަވެސް، އެއުރެންނަށް ކަލޭ ކުޅަ އަނިޔާއިން، ކަލެޔަށް ދެވިފައި އޮތީ ކޮން ނިއުމަތެއް ހެއްޔެވެ؟)","",""],["","","","قال فرعون وما رب العالمين","ފިރްޢައުނު ދެންނެވިއެވެ. (ކަލޭގެފާނު އެފަރާތަކުން ރަސޫލުކަމާއިގެން ވަޑައިގެންނެވި) އާލަމްތަކުގެ ވެރިރަސްކަލާނގެއަކީ ކޮބައިހެއްޔެވެ؟","",""],["","","","قال رب السماوات والأرض وما بينهما إن كنتم موقنين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އެއީ އުޑުތަކާއި، ބިމާއި، އެދެމެދުގައިވާހާ އެއްޗެއްގެ ވެރިރަސްކަލާނގެއެވެ. ތިޔަބައިމީހުން އެކަން ޔަގީންކުރާ ކަމުގައިވާނަމައެވެ.","",""],["","","","قال لمن حوله ألا تستمعون","އޭނާގެ ވަށައިގެންތިބި (ބޮޑުންގެ) މީހުންނަށް އޭނާ ބުންޏެވެ. ކަލޭމެންނަކަށް ނީވޭހެއްޔެވެ؟","",""],["","","","قال ربكم ورب آبائكم الأولين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އެއީ ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއެވެ. އަދި ތިޔަބައިމީހުންގެ އިސްވެދިޔަ ކާބަފައިންގެވެސް ވެރިރަސްކަލާނގެއެވެ.","",""],["","","","قال إن رسولكم الذي أرسل إليكم لمجنون","އޭނާ ބުންޏެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ގާތަށް ފޮނުއްވާފައިވާ ތިޔަބައިމީހުންގެ ރަސޫލަކީ، މޮޔައެއްކަން ކަށަވަރެވެ.","",""],["","","","قال رب المشرق والمغرب وما بينهما إن كنتم تعقلون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އެއީ މަޝްރިގާއި، މަޣްރިބާއި، އެދެމެދުގައިވާހާ ތަކެއްޗެއްގެ ވެރިރަސްކަލާނގެއެވެ. ތިޔަބައިމީހުން އެކަން ވިސްނާކަމުގައި ވާނަމައެވެ.","",""],["","","","قال لئن اتخذت إلها غيري لأجعلنك من المسجونين","އޭނާ ދެންނެވިއެވެ. ކަލޭގެފާނު ތިމަންފިޔަވައި އެހެން އިލާހަކު ހިއްޕަވައިފިނަމަ، ހަމަކަށަވަރުން، ހުރަގޭގައި ހައްޔަރުކުރެވިގެންވާ މީހުންގެ ތެރެއަށް ކަލޭގެފާނު ލާހުށީމެވެ.","",""],["","","","قال أولو جئتك بشيء مبين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. (ތިމަންކަލޭގެފާނުގެ ރަސޫލުކަމުގެ މައްޗަށް) ބަޔާން ވެގެންވާ ދަލީލެއް ކަލޭގެ ގާތަށް ގެންނެވި ނަމަވެސް ހެއްޔެވެ؟","",""],["","","","قال فأت به إن كنت من الصادقين","އޭނާ ދެންނެވިއެވެ. ކަލޭގެފާނު ތެދުވެރިންގެ ތެރެއިން ވާނަމަ، ފަހެ، ދަލީލުގެންނަވައިބައްލަވާށެވެ!","",""],["","","","فألقى عصاه فإذا هي ثعبان مبين","ދެން އެކަލޭގެފާނުގެ އަސާކޮޅު އެކަލޭގެފާނު އެއްލެވިއެވެ. ފަހެ، އެހިނދު އެ އަސާކޮޅު، ފާޅުވެގެންވާ ހަރުފަޔަކަށް ވެއްޖެއެވެ.","",""],["","","","ونزع يده فإذا هي بيضاء للناظرين","އަދި އެކަލޭގެފާނުގެ އަތްޕުޅު ނެރުއްވިއެވެ. ފަހެ، އެހިނދު، ބަލަންތިބި މީހުންނަށް އެ އަތްޕުޅު ފެންނަންއޮތީ (ވިދަވިދާއޮތް) ހުދު އަތްޕުޅެއް ކަމުގައެވެ.","",""],["","","","قال للملإ حوله إن هذا لساحر عليم","އޭނާގެ ވަށައިގެންވާ ބޮޑުންނަށް އޭނާ ބުންޏެވެ. ހަމަކަށަވަރުން، މިއީ މޮޅަށް ދަންނަ ޖާދޫގަރެއްކަން ކަށަވަރެވެ.","",""],["","","","يريد أن يخرجكم من أرضكم بسحره فماذا تأمرون","އެކަލޭގެފާނު އެދިވަޑައިގަންނަވަނީ، އެކަލޭގެފާނުގެ ޖާދޫގެ ބާރުގައި ތިޔަބައިމީހުންގެ ބިމުން ތިޔަބައިމީހުން ނެރެލާށެވެ. ވީމާ، ތިޔަބައިމީހުން އަމުރުކުރާގޮތަކީ ކޮބައިހެއްޔެވެ؟","",""],["","","","قالوا أرجه وأخاه وابعث في المدائن حاشرين","އެއުރެން ބުނޫއެވެ. އެކަލޭގެފާނާއި، އެކަލޭގެފާނުގެ އަޚު، އިހަށް ބައިތިއްބާށެވެ! އަދި (މީހުން) އެއްކުރުމަށް ގޮވާބަޔަކު ރަށުތެރެޔަށް ފޮނުވާށެވެ!","",""],["","","","يأتوك بكل سحار عليم","އޭރުން އެއުރެން (ގޮސް) މޮޅަށްދަންނަ ހުރިހާ ބޮޑެތި ޖާދޫގަރުން ކަލޭގެ ގާތަށް ގެނެސްދޭނެތެވެ.","",""],["","","","فجمع السحرة لميقات يوم معلوم","ފަހެ، އެނގިގެންވާ ދުވަހެއްގެ ކަނޑައެޅިގެންވާ ވަގުތަކަށް ޖާދޫގަރުން އެއްކޮށްފިއެވެ.","",""],["","","","وقيل للناس هل أنتم مجتمعون","އަދި މީސްތަކުންނަށް ބުންޏެވެ. ތިޔަބައިމީހުން އެއްވާނޫހެއްޔެވެ؟","",""],["","","","لعلنا نتبع السحرة إن كانوا هم الغالبين","އެ ޖާދޫގަރުންނަކީ، ގަދަވިމީހުން ކަމުގައި ވެއްޖެނަމަ، އަހުރެމެން އެއުރެންނަށް ތަބާ ވުމަށްޓަކައެވެ.","",""],["","","","فلما جاء السحرة قالوا لفرعون أئن لنا لأجرا إن كنا نحن الغالبين","ފަހެ، އެ ޖާދޫގަރުން އައިހިނދު، އެއުރެން ފިރްޢައުނަށް ބުނޫއެވެ. ތިމަންމެން މޮޅުވެއްޖެނަމަ، ހަމަކަށަވަރުން، ތިމަންމެންނަށް އުޖޫރައެއް އޮންނާނެ ހެއްޔެވެ؟","",""],["","","","قال نعم وإنكم إذا لمن المقربين","އޭނާ ބުންޏެވެ. އާނއެކެވެ! އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުން އޭރުން ވާހުށީ، ގާތްކުރެވިގެންވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["","","","قال لهم موسى ألقوا ما أنتم ملقون","މޫސާގެފާނު އެއުރެންނަށް ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން (ޖާދޫގެގޮތުން) އުކަންހުރި ތަކެތި އުކާށެވެ!","",""],["","","","فألقوا حبالهم وعصيهم وقالوا بعزة فرعون إنا لنحن الغالبون","ފަހެ، އެއުރެންގެ ވާބުރިތަކާއި، އަސާތައް އެއުރެން އުކޫއެވެ. އަދި އެއުރެން ބުނޫއެވެ. ފިރްޢައުނުގެ ޢިއްޒަތް ގަންދީ ބުނަމެވެ. ހަމަކަށަވަރުން، ގަދަވާނެ ބަޔަކީ ތިމަންމެންކަން ކަށަވަރެވެ.","",""],["","","","فألقى موسى عصاه فإذا هي تلقف ما يأفكون","ދެން މޫސާގެފާނު އެކަލޭގެފާނުގެ އަސާކޮޅު އެއްލެވިއެވެ. ފަހެ، އެހާރުން އެ އަސާކޮޅު އެއުރެން ދޮގުން ހަދައިގެން ދެއްކި ތަކެތި ކައި ދިރުވައިފިއެވެ.","",""],["","","","فألقي السحرة ساجدين","ފަހެ، އެ ޖާދޫގަރުން ސަޖިދަށް ތިރިވެއްޖައޫއެވެ.","",""],["","","","قالوا آمنا برب العالمين","އެއުރެން ބުނޫއެވެ. އާލަމްތަކުގެ ވެރިރަސްކަލާނގެއަށް ތިމަންމެން އީމާން ވެއްޖައީމުއެވެ.","",""],["","","","رب موسى وهارون","(އެއީ) މޫސާގެފާނާއި، ހާރޫނުގެފާނުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["","","","قال آمنتم له قبل أن آذن لكم إنه لكبيركم الذي علمكم السحر فلسوف تعلمون لأقطعن أيديكم وأرجلكم من خلاف ولأصلبنكم أجمعين","އޭނާ ބުންޏެވެ. ތިޔަބައިމީހުންނަށް ތިމަން އިޒުނަ ދިނުމުގެ ކުރީގައި، ތިޔަބައިމީހުން އެކަލޭގެފާނަށް އީމާން ވެއްޖައީމުއެވެ. ހަމަކަށަވަރުން، އެކަލޭގެފާނީ ތިޔަބައިމީހުންނަށް ޖާދޫދަސްކޮށްދިން ތިޔަބައިމީހުންގެ ބޮޑުމީހާއެވެ. ފަހެ، ތިޔަބައިމީހުންނަށް ނިކަންހުރެ އެނގޭހުށްޓެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ އަތްތަކާއި، ފައިތައް ތަފާތުވާގޮތަށް (އެބަހީ: ކަނާތާއި ވާތުފައި، ނުވަތަ ވާތާއި ކަނާތުފައި) ތިމަން ބުރިކުރާހުށީމެވެ. އަދި ހަމަކަށަވަރުން، ތިޔަ ހުރިހާ އެންމެން ޞަލީބަށް އަރުވާހުށީމެވެ.","",""],["","","","قالوا لا ضير إنا إلى ربنا منقلبون","އެއުރެން ބުނޫއެވެ. (އެކަމުގައި) ގެއްލުމެއްނެތެވެ. ހަމަކަށަވަރުން، ތިމަންމެން އެނބުރި ދާހުށީ، ތިމަންމެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","إنا نطمع أن يغفر لنا ربنا خطايانا أن كنا أول المؤمنين","ތިމަންމެން އެންމެފުރަތަމަ އީމާން ވީބަޔެއްކަމުގައިވުމުގެ ސަބަބުން، ހަމަކަށަވަރުން، ތިމަންމެންގެ ވެރިރަސްކަލާނގެ ތިމަންމެންގެ ކުށްފާފަތައް ފުއްސެވުމަށް ތިމަންމެން ދަހިވެތިވަމުއެވެ.","",""],["","","","وأوحينا إلى موسى أن أسر بعبادي إنكم متبعون","ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް ވަހީކުރެއްވީމެވެ. ކަލޭގެފާނު ތިމަންރަސްކަލާނގެ އަޅުންނާއިގެން، ރޭގަނޑު ހިންގަވައިވަޑައިގަންނަވާށެވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ފަހަތުން ބަޔަކު ދާނެތެވެ. (އެބަހީ: ތިޔަބައިމީހުންގެ ފަހަތުން، ފިރްޢައުނާއި އޭނާގެ ލަޝްކަރު ދާނެތެވެ.)","",""],["","","","فأرسل فرعون في المدائن حاشرين","ފަހެ، ފިރްޢައުނު، މީހުން އެއްކުރުމަށް ގޮވާބަޔަކު ރަށުތެރެޔަށް ފޮނުވިއެވެ.","",""],["","","","إن هؤلاء لشرذمة قليلون","ހަމަކަށަވަރުން، މިބައިމީހުންނީ، (އެބަހީ: އިސްރާއީލުގެދަރިންނަކީ) ނިކަމެތި މަދުމީސްކޮޅެއްކަން ކަށަވަރެވެ.","",""],["","","","وإنهم لنا لغائظون","އަދި ހަމަކަށަވަރުން، އެއުރެންނީ ތިމަންމެން ރުޅިއަރުވާ ބަޔަކުކަން ކަށަވަރެވެ.","",""],["","","","وإنا لجميع حاذرون","އަދި ހަމަކަށަވަރުން، ތިމަންމެންނީ (ކަންކަމަށް) ރައްކާތެރިވެ، ތައްޔާރަށްތިބޭ ބަޔަކީމުއެވެ.","",""],["","","","فأخرجناهم من جنات وعيون","ފަހެ، ތިމަންރަސްކަލާނގެ، ފެންއާރުތަކާއި، ބަގީޗާތަކުންނާއި، (ރަނާއި ރިހީގެ) ޚަޒާނާ ތަކުންނާއި، މަތިވެރި މާތް މަގާމް ތަކުން އެއުރެން (އެބަހީ: ފިރްޢައުނާއި، އޭނާގެ ގައުމުގެމީހުން) ބޭރުކުރެއްވީމެވެ.","",""],["","","","وكنوز ومقام كريم","ފަހެ، ތިމަންރަސްކަލާނގެ، ފެންއާރުތަކާއި، ބަގީޗާތަކުންނާއި، (ރަނާއި ރިހީގެ) ޚަޒާނާ ތަކުންނާއި، މަތިވެރި މާތް މަގާމް ތަކުން އެއުރެން (އެބަހީ: ފިރްޢައުނާއި، އޭނާގެ ގައުމުގެމީހުން) ބޭރުކުރެއްވީމެވެ.","",""],["","","","كذلك وأورثناها بني إسرائيل","އެކަންކުރީ އެފަދައިންނެވެ. އަދި އިސްރާއީލުގެދަރިންނަށް ތިމަންރަސްކަލާނގެ އެތަކެތި ވާރުތަކުރެއްވީމެވެ.","",""],["","","","فأتبعوهم مشرقين","ފަހެ، އެއުރެން (އެބަހީ: ފިރްޢައުނާއި އޭނާގެ ގައުމުގެމީހުން) އަނެއްބައި މީހުންގެ ފަހަތުންގޮސް އަރައިހަމަކުރީ، އިރުއެރި ވަގުތުގައެވެ.","",""],["","","","فلما تراءى الجمعان قال أصحاب موسى إنا لمدركون","ފަހެ، އެއުރެން އެއްބަޔަކު އަނެއްބަޔަކަށް ފެނުނުހިނދު، މޫސާގެފާނުގެ އަޞްޙާބުން ދެންނެވޫއެވެ. ހަމަކަށަވަރުން، އެއުރެން ތިމަންމެން އަތުލައިގަންނާނެތެވެ.","",""],["","","","قال كلا إن معي ربي سيهدين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ހަމަކަށަވަރުން، ތިމަންގެ ވެރިރަސްކަލާނގެ ތިމަންނާއާއެކު (ނަސްރު ދެއްވުމުގައި) ވޮޑިގެންވެއެވެ. އެކަލާނގެ ތިމަންނާއަށް މަގުދައްކަވާނެތެވެ.","",""],["","","","فأوحينا إلى موسى أن اضرب بعصاك البحر فانفلق فكان كل فرق كالطود العظيم","ފަހެ، ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް ވަހީކުރެއްވީމެވެ. ކަލޭގެފާނުގެ އަސާކޮޅުން ކަނޑުގައި ޖައްސަވާށެވެ! ދެން (މޫސާގެފާނު ޖެއްސެވުމުން، ބާރަ ބަޔަށް) އެ ކަނޑު އިރައިގެން ހިނގައްޖެއެވެ. އެއިން ކޮންމެ ބައެއް، ބޮޑު ފަރުބަދައެއް ފަދައިންވިއެވެ.","",""],["","","","وأزلفنا ثم الآخرين","ތިމަންރަސްކަލާނގެ އަނެއްބައިމީހުން (އެބަހީ: ފިރްޢައުނާއި އޭނާގެ ގައުމުގެމީހުން) އެތަނަށް ކައިރި ކުރެއްވީމެވެ.","",""],["","","","وأنجينا موسى ومن معه أجمعين","އަދި ތިމަންރަސްކަލާނގެ މޫސާގެފާނާއި، އެކަލޭގެފާނުގެ އަރިހުގައިވާ މީހުންގެ އެންމެން (ޣަރަގުން) ސަލާމަތް ކުރެއްވީމެވެ.","",""],["","","","ثم أغرقنا الآخرين","ދެން ތިމަންރަސްކަލާނގެ އެހެންމީހުން (އެބަހީ: ކާފިރުން) ޣަރަގުކުރެއްވީމެވެ.","",""],["","","","إن في ذلك لآية وما كان أكثرهم مؤمنين","ހަމަކަށަވަރުން، އެކަންތަކުގައި (ﷲގެ ކުޅަދުންވަންތަކަމުގެ) ހެތްކެއްވާކަން ކަށަވަރެވެ. އަދި އެއުރެންކުރެ ގިނަމީހުން، އީމާންވާ ބަޔަކު ކަމުގައި ނުވެތެވެ.","",""],["","","","وإن ربك لهو العزيز الرحيم","އަދި ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ޢަޒީޒުވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","واتل عليهم نبأ إبراهيم","(އޭ މުޙައްމަދުގެފާނެވެ!) ކަލޭގެފާނު، އެއުރެންނަށް އިބްރާހީމްގެފާނުގެ ޚަބަރު ކިޔައިދެއްވާށެވެ!","",""],["","","","إذ قال لأبيه وقومه ما تعبدون","(އެއީ) އެކަލޭގެފާނު، އެކަލޭގެފާނުގެ ބައްޕައަށާއި، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް، ތިޔަބައިމީހުން ތިޔަ އަޅުކަންކުރަނީ ކޮންއެއްޗަކަށްހޭ، ވިދާޅުވި ހިނދެވެ.","",""],["","","","قالوا نعبد أصناما فنظل لها عاكفين","އެއުރެން ދެންނެވޫއެވެ. ތިމަންމެން އަޅުކަންކުރަނީ، ބުދުތަކަކަށެވެ. ފަހެ، އެތަކެއްޗަށް އަޅުކަންކުރުންމަތީ ތިމަންމެން ދެމިތިބޭނޫއެވެ.","",""],["","","","قال هل يسمعونكم إذ تدعون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން އެތަކެއްޗަށް ދުއާ ކޮށް ގޮވާހިނދު، އެތަކެއްޗަށް ތިޔަބައިމީހުންގެ އަޑު އިވޭހެއްޔެވެ؟","",""],["","","","أو ينفعونكم أو يضرون","ނުވަތަ އެތަކެތި ތިޔަބައިމީހުންނަށް މަންފާއެއް ކޮށްދޭހެއްޔެވެ؟ ނުވަތަ ގެއްލުމެއް ދޭހެއްޔެވެ؟","",""],["","","","قالوا بل وجدنا آباءنا كذلك يفعلون","އެއުރެން ދެންނެވޫއެވެ. އަދި ކީއްހެއްޔެވެ؟ ތިމަންމެންގެ ކާބަފައިން އެފަދައިން ކަންތައްކުރާތީ ތިމަންމެން ދުށީމުއެވެ.","",""],["","","","قال أفرأيتم ما كنتم تعبدون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންނާއި، ތިޔަބައިމީހުންގެ އިސްވެދިޔަ ކާބަފައިން އަޅުކަންކުރި ތަކެއްޗާމެދު ތިޔަބައިމީހުން ވިސްނައި ބެލީމުހެއްޔެވެ؟","",""],["","","","أنتم وآباؤكم الأقدمون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންނާއި، ތިޔަބައިމީހުންގެ އިސްވެދިޔަ ކާބަފައިން އަޅުކަންކުރި ތަކެއްޗާމެދު ތިޔަބައިމީހުން ވިސްނައި ބެލީމުހެއްޔެވެ؟","",""],["","","","فإنهم عدو لي إلا رب العالمين","ފަހެ، ހަމަކަށަވަރުން، އެތަކެއްޗަކީ، ތިމަންކަލޭގެފާނުގެ އަދުއްވުންނެވެ. (އެތަކެއްޗަށް އަޅުކަމެއް ނުކުރައްވާނަމެވެ.) އެހެނެއްކަމަކު، ތިމަންކަލޭގެފާނު އަޅުކަންކުރައްވާނީ، އާލަމްތަކުގެ ވެރިރަސްކަލާނގެއަށެވެ.","",""],["","","","الذي خلقني فهو يهدين","އެކަލާނގެއީ، ތިމަން ހެއްދެވި ރަސްކަލާނގެއެވެ. ފަހެ، އެކަލާނގެ ތިމަންނާއަށް ތެދުމަގު ދައްކަވަތެވެ.","",""],["","","","والذي هو يطعمني ويسقين","އަދި އެކަލާނގެއީ، ތިމަންނާއަށް ކާންދެއްވާ، އަދި ބޯންދެއްވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وإذا مرضت فهو يشفين","އަދި ތިމަން ބަލިވެއްޖެނަމަ، ބަލި ފަސޭހަކުރައްވަނީ، ހަމަ އެކަލާނގެއެވެ.","",""],["","","","والذي يميتني ثم يحيين","އަދި އެކަލާނގެއީ، ތިމަން މަރުގަންނަވައި، ދެން ތިމަން ދިރުއްވާނޭ ރަސްކަލާނގެއެވެ.","",""],["","","","والذي أطمع أن يغفر لي خطيئتي يوم الدين","އަދި ގިޔާމަތް ދުވަހުން މިއަޅާގެ ފާފަފުއްސެވުމަށް މިއަޅާ އެދެނީ، އެކަލާނގެ ހަޒުރަތުންނެވެ.","",""],["","","","رب هب لي حكما وألحقني بالصالحين","އަޅުގެ ވެރިރަސްކަލާކޮ! މިއަޅާއަށް އިލްމާއި، ވިސްނުން ދެއްވާނދޭވެ! އަދި ސާލިހު ންގެތެރެއިން މިއަޅާ ލައްވާނދޭވެ!","",""],["","","","واجعل لي لسان صدق في الآخرين","ފަހުން އަންނަމީހުންގެ ދޫމަތީގައި، މިއަޅާގެ ތާރީފާއި ޘަނާ ލައްވާނދޭވެ!","",""],["","","","واجعلني من ورثة جنة النعيم","އަދި ނިއުމަތްގެ ސުވަރުގެ ވާރުތަވާ މީހުންގެ ތެރެއިން، މިއަޅާ ލައްވާނދޭވެ!","",""],["","","","واغفر لأبي إنه كان من الضالين","އަދި މިއަޅާގެ ބައްޕާއަށް ފާފަފުއްސަވާނދޭވެ! ހަމަކަށަވަރުން، އޭނާވަނީ މަގުފުރެދުނު މީހުންގެ ތެރެއިންނެވެ.","",""],["","","","ولا تخزني يوم يبعثون","އަދި އެއުރެން (އެބަހީ: މީސްތަކުން) މަހުޝަރަށް ފޮނުއްވާދުވަހު، މިއަޅާ ނިކަމެތި ނުކުރައްވާނދޭވެ!","",""],["","","","يوم لا ينفع مال ولا بنون","އެދުވަހަކީ، މުދަލެއްވިޔަސް، އަދި ދަރިންނެއްވިޔަސް، މަންފާއެއް ނުކުރާނެ ދުވަހެވެ.","",""],["","","","إلا من أتى الله بقلب سليم","ސަލާމަތްވެގެންވާ ހިތަކާއިގެން ﷲގެ ހަޒުރަތަށް އައިމީހަކަށް މެނުވީއެވެ.","",""],["","","","وأزلفت الجنة للمتقين","އަދި ތަގުވާވެރިންނަށް ސުވަރުގެ ކައިރިކުރައްވާނެތެވެ.","",""],["","","","وبرزت الجحيم للغاوين","އަދި ކާފިރުންނަށް ނަރަކަ ފާޅުކުރައްވާނެތެވެ.","",""],["","","","وقيل لهم أين ما كنتم تعبدون","އަދި އެއުރެންނަށް އަންގަވާނެތެވެ. ތިޔަބައިމީހުން، ﷲ ފިޔަވައި އަޅުކަން ކޮށްއުޅުނު ތަކެތި ކޮބައިހެއްޔެވެ؟ އެތަކެތި ތިޔަބައިމީހުންނަށް ނަސްރު ދޭހެއްޔެވެ؟ ނުވަތަ އެތަކެއްޗަށް ނަސްރު ލިބޭހެއްޔެވެ؟","",""],["","","","من دون الله هل ينصرونكم أو ينتصرون","އަދި އެއުރެންނަށް އަންގަވާނެތެވެ. ތިޔަބައިމީހުން، ﷲ ފިޔަވައި އަޅުކަން ކޮށްއުޅުނު ތަކެތި ކޮބައިހެއްޔެވެ؟ އެތަކެތި ތިޔަބައިމީހުންނަށް ނަސްރު ދޭހެއްޔެވެ؟ ނުވަތަ އެތަކެއްޗަށް ނަސްރު ލިބޭހެއްޔެވެ؟","",""],["","","","فكبكبوا فيها هم والغاوون","ފަހެ، އެ ބުދުތަކާއި، ކާފިރު ވީ މީހުންނާއި، އިބްލީސްގެ ލަޝްކަރާއި، އެންމެން އެ ނަރަކައިގެ ތެރެއަށް ބޯކޮޅުވަތަށް އުއްކަވާނެތެވެ.","",""],["","","","وجنود إبليس أجمعون","ފަހެ، އެ ބުދުތަކާއި، ކާފިރު ވީ މީހުންނާއި، އިބްލީސްގެ ލަޝްކަރާއި، އެންމެން އެ ނަރަކައިގެ ތެރެއަށް ބޯކޮޅުވަތަށް އުއްކަވާނެތެވެ.","",""],["","","","قالوا وهم فيها يختصمون","އެއުރެން އެ ނަރަކައިގައި އަރާރުންވާ ޙާލު ބުނާނެތެވެ.","",""],["","","","تالله إن كنا لفي ضلال مبين","ﷲ ގަންދީބުނަމުއެވެ. ހަމަކަށަވަރުން، ތިމަންމެންވަނީ، ބަޔާން ވެގެންވާ ފުރެދުމެއްގައެވެ.","",""],["","","","إذ نسويكم برب العالمين","(އަޅުކަން ކުރުމުގައި) އާލަމްތަކުގެ ވެރިރަސްކަލާނގެއާ ތިޔަބައިމީހުންނާ ހަމަހަމަކޮށްގެން ތިމަންމެން އުޅުނު ހިނދުގައެވެ.","",""],["","","","وما أضلنا إلا المجرمون","އަދި ތިމަންމެން މަގުފުރެއްދީ، ކުށްވެރިން ފިޔަވައި އެހެން ބައެއްނޫނެވެ.","",""],["","","","فما لنا من شافعين","ފަހެ، ތިމަންމެންނަށް އެއްވެސް ޝަފާއަތް ތެރިޔަކު ނުވެއެވެ.","",""],["","","","ولا صديق حميم","އަދި ގާތް ރަހުމަތް ތެރިޔަކުވެސް ނުވެއެވެ.","",""],["","","","فلو أن لنا كرة فنكون من المؤمنين","ތިމަންމެންނަށް އަދި އެއްފަހަރު (ދުނިޔެއަށް) ރުޖޫއަ ވުމެއް ލިބޭނެ ނަމައެވެ. ފަހެ، އޭރުން ތިމަންމެން މުއުމިނުންގެ ތެރެއިން ވާހުށީމުއެވެ.","",""],["","","","إن في ذلك لآية وما كان أكثرهم مؤمنين","ހަމަކަށަވަރުން، އެކަންތަކުގައި (ﷲގެ ކުޅަދުންވަންތަކަމުގެ) ހެތްކެއްވާކަން ކަށަވަރެވެ. އަދި އެއުރެންކުރެ ގިނަމީހުން، އީމާންވާ ބަޔަކު ކަމުގައި ނުވެތެވެ.","",""],["","","","وإن ربك لهو العزيز الرحيم","އަދި ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ޢަޒީޒުވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","كذبت قوم نوح المرسلين","ނޫޙުގެފާނުގެ ގައުމުގެމީހުން ރަސޫލުން ދޮގުކުރޫއެވެ.","",""],["","","","إذ قال لهم أخوهم نوح ألا تتقون","(އެއީ) އެއުރެންނަށް އެއުރެންގެ އަޚު، ނޫޙުގެފާނު ވިދާޅުވި ހިނދުގައެވެ. ތިޔަބައިމީހުން (ﷲއަށް) ތަގުވާވެރި ނުވަނީ ހެއްޔެވެ؟","",""],["","","","إني لكم رسول أمين","ހަމަކަށަވަރުން، އަހުރެންނީ ތިޔަބައިމީހުންގެ ގާތަށް ފޮނުއްވާފައިވާ އަމާނަތް ތެރި ރަސޫލަކީމެވެ.","",""],["","","","فاتقوا الله وأطيعون","ފަހެ، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ތިޔަބައިމީހުން އަހުރެންނަށް ކިޔަމަންތެރިވާށެވެ!","",""],["","","","وما أسألكم عليه من أجر إن أجري إلا على رب العالمين","އަދި އަހުރެން އެ ރަސޫލު ކަން އިއްވުމަކަށް ތިޔަބައިމީހުންގެ ކިބައިން އުޖޫރައަކަށް ނޭދެމެވެ. އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން މެނުވީ، އަހުރެންނަށް ސަވާބު ދެއްވުމެއްނުވެއެވެ.","",""],["","","","فاتقوا الله وأطيعون","ފަހެ، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ތިޔަބައިމީހުން އަހުރެންނަށް ކިޔަމަންތެރިވާށެވެ!","",""],["","","","قالوا أنؤمن لك واتبعك الأرذلون","އެއުރެން ދެންނެވޫއެވެ. ކަލޭގެފާނަށް ތަބާ ވެގެންތިބީ، ދެރަ ނިކަމެތިން ކަމުގައިވާއިރު، ތިމަންމެން ކަލޭގެފާނަށް އީމާން ވާނެތޯއެވެ؟","",""],["","","","قال وما علمي بما كانوا يعملون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އެއުރެން ކޮށްއުޅުނު ޢަމަލާމެދު ތިމަންކަލޭގެފާނަށް އެނގިގެންވަނީ ކޮންއެއްޗެއް ހެއްޔެވެ؟","",""],["","","","إن حسابهم إلا على ربي لو تشعرون","ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް މެނުވީ، އެއުރެންގެ ހިސާބު ބެއްލެވުމެއް ނުވެއެވެ. ތިޔަބައިމީހުންނަށް (އެކަން) އެނގޭނަމައެވެ.","",""],["","","","وما أنا بطارد المؤمنين","އަދި އީމާން ވެގެންތިބި މީހުން ފަހައި ދުރަށްލާމީހަކު ކަމުގައި ތިމަންކަލޭގެފާނު ނުވަމެވެ.","",""],["","","","إن أنا إلا نذير مبين","ބަޔާން ވެގެންހުރި އިންޒާރުކުރައްވާ ބޭކަލަކު ކަމުގައި މެނުވީ ތިމަންކަލޭގެފާނު ނުވަމެވެ.","",""],["","","","قالوا لئن لم تنته يا نوح لتكونن من المرجومين","އެއުރެން ދެންނެވޫއެވެ. އޭ ނޫޙުގެފާނެވެ! ކަލޭގެފާނު (ތިޔަކަންތައް) ހުށްޓައިނުލެއްވިނަމަ، ހަމަކަށަވަރުން، ގަލުންތަޅައި މަރައިލެވޭ މީހުންގެ ތެރޭގައި، ކަލޭގެފާނު ވާހުށްޓެވެ.","",""],["","","","قال رب إن قومي كذبون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، މިއަޅާގެ ގައުމުގެމީހުން މިއަޅާ ދޮގުކޮށްފޫއެވެ.","",""],["","","","فافتح بيني وبينهم فتحا ونجني ومن معي من المؤمنين","ފަހެ، މިއަޅާއާއި، އެއުރެންނާ ދެމެދުގައި އިންޞާފުކުރައްވައި، މިއަޅާއާއި، މިއަޅާއާ އެކުގައިވާ މުއުމިނު ތަކުން ސަލާމަތް ކުރައްވާނދޭވެ!","",""],["","","","فأنجيناه ومن معه في الفلك المشحون","ފަހެ، ބަރާވެވިފައިވާ ނާކޮޅުގައި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނާއި، އެކަލޭގެފާނުގެ އަރިހުގައިވާ މީހުން ސަލާމަތް ކުރެއްވީމެވެ.","",""],["","","","ثم أغرقنا بعد الباقين","ދެން ތިމަންރަސްކަލާނގެ އެއަށްފަހު ތިބި އެންމެން ޣަރަގުކުރެއްވީމެވެ.","",""],["","","","إن في ذلك لآية وما كان أكثرهم مؤمنين","ހަމަކަށަވަރުން، އެކަންތަކުގައި (ﷲގެ ކުޅަދުންވަންތަކަމުގެ) ހެތްކެއް ވާކަން ކަށަވަރެވެ. އަދި އެއުރެންކުރެ ގިނަމީހުން އީމާންވާ ބަޔަކު ކަމުގައި ނުވެއެވެ.","",""],["","","","وإن ربك لهو العزيز الرحيم","އަދި ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ ޢަޒީޒުވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","كذبت عاد المرسلين","ޢާދު ބާގައިމީހުން ރަސޫލުން ދޮގުކުރޫއެވެ.","",""],["","","","إذ قال لهم أخوهم هود ألا تتقون","(އެއީ) އެއުރެންގެ އަޚު، ހޫދުގެފާނު އެއުރެންނަށް ވިދާޅުވި ހިނދުގައެވެ. ތިޔަބައިމީހުން (ﷲއަށް) ތަގުވާވެރި ނުވަނީހެއްޔެވެ؟","",""],["","","","إني لكم رسول أمين","ހަމަކަށަވަރުން، އަހުރެންނީ، ތިޔަބައިމީހުންގެ ގާތަށް ފޮނުއްވާފައިވާ އަމާނަތް ތެރި ރަސޫލަކީމެވެ.","",""],["","","","فاتقوا الله وأطيعون","ފަހެ، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ތިޔަބައިމީހުން އަހުރެންނަށް ކިޔަމަންތެރިވާށެވެ!","",""],["","","","وما أسألكم عليه من أجر إن أجري إلا على رب العالمين","އަދި އަހުރެން އެ ރަސޫލު ކަން އިއްވުމަކަށް ތިޔަބައިމީހުންގެ ކިބައިން އުޖޫރައަކަށް ނޭދެމެވެ. އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން މެނުވީ އަހުރެންނަށް ސަވާބު ދެއްވުމެއް ނުވެތެވެ.","",""],["","","","أتبنون بكل ريع آية تعبثون","ތިޔަބައިމީހުން ބޭކާރު ކުޅުންތައް ކުޅުމަށް ކޮންމެ އުސްތަނެއްގައި ބިނާއެއް ހަދަނީހެއްޔެވެ؟","",""],["","","","وتتخذون مصانع لعلكم تخلدون","އަދި ތިޔަބައިމީހުން (އެތަންތާނގައި މަރުނުވެ) އަބަދަށް ދެމިތިބޭނޭކަމަށް ގަނޑުވަރުތައް ހަދަނީ ހެއްޔެވެ؟","",""],["","","","وإذا بطشتم بطشتم جبارين","އަދި ތިޔަބައިމީހުން ގަދަފަދަކަން ދައްކާހިނދު (އެއްވެސް ރަޙިމެއްނެތި) ޖައްބާރުންގެ ގޮތުގައި ގަދަފަދަކަން ދައްކަމުއެވެ.","",""],["","","","فاتقوا الله وأطيعون","ފަހެ، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ތިޔަބައިމީހުން އަހުރެންނަށް ކިޔަމަންތެރިވާށެވެ!","",""],["","","","واتقوا الذي أمدكم بما تعلمون","ތިޔަބައިމީހުން ދަންނަ ނިއުމަތް ތަކުން ތިޔަބައިމީހުންނަށް މަދަދު ދެއްވި ރަސްކަލާނގެއަށް ތަގުވާވެރިވާށެވެ!","",""],["","","","أمدكم بأنعام وبنين","ނަޢަމް ސޫތްޕާއި، ދަރިންނާއި، ބަގީޗާތަކާއި، ފެންއާރުތަކުން އެކަލާނގެ ތިޔަބައިމީހުންނަށް ނިއުމަތް ދެއްވިއެވެ.","",""],["","","","وجنات وعيون","ނަޢަމް ސޫތްޕާއި، ދަރިންނާއި، ބަގީޗާތަކާއި، ފެންއާރުތަކުން އެކަލާނގެ ތިޔަބައިމީހުންނަށް ނިއުމަތް ދެއްވިއެވެ.","",""],["","","","إني أخاف عليكم عذاب يوم عظيم","ހަމަކަށަވަރުން، ބޮޑުވެގެންވާ ދުވަހެއްގެ އަޒާބަށް ތިޔަބައިމީހުންނާމެދު ތިމަންކަލޭގެފާނު ބިރުފުޅުގަނެތެވެ.","",""],["","","","قالوا سواء علينا أوعظت أم لم تكن من الواعظين","އެއުރެން ދެންނެވޫއެވެ. ކަލޭގެފާނު ނަސޭހަތް ދެއްވިޔަސް، ނުވަތަ ނަސޭހަތް ދޭ މީހުންގެ ތެރެއިން ކަލޭގެފާނު ވެވަޑައިނުގަތަސް، ތިމަންމެންނަށް ހަމަހަމަވެގެންވެއެވެ.","",""],["","","","إن هذا إلا خلق الأولين","މިއީ އިސްވެދިޔަމީހުންގެ އާދަކަމުގައި ނޫނީ ނުވެތެވެ.","",""],["","","","وما نحن بمعذبين","އަދި އަޒާބު ލިބޭނޭ ބަޔަކު ކަމުގައި ތިމަންމެން ނުވަމުއެވެ.","",""],["","","","فكذبوه فأهلكناهم إن في ذلك لآية وما كان أكثرهم مؤمنين","ފަހެ، އެއުރެން އެކަލޭގެފާނު (އެބަހީ: ހޫދުގެފާނު) ދޮގުކުރޫއެވެ. ދެން ތިމަންރަސްކަލާނގެ އެއުރެން ހަލާކު ކުރެއްވީމެވެ. ހަމަކަށަވަރުން، އެކަންތަކުގައި (ﷲގެ ކުޅަދުންވަންތަކަމުގެ) ހެތްކެއްވާކަން ކަށަވަރެވެ. އަދި އެއުރެންކުރެ ގިނަމީހުން، އީމާންވާ ބަޔަކު ކަމުގައި ނުވެތެވެ.","",""],["","","","وإن ربك لهو العزيز الرحيم","އަދި ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ޢަޒީޒުވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","كذبت ثمود المرسلين","ޘަމޫދު ބާގައިމީހުން، ރަސޫލުން ދޮގުކުރޫއެވެ.","",""],["","","","إذ قال لهم أخوهم صالح ألا تتقون","(އެއީ) އެއުރެންގެ އަޚު، ސާލިހުގެފާނު އެއުރެންނަށް ވިދާޅުވި ހިނދުގައެވެ. ތިޔަބައިމީހުން (ﷲއަށް) ތަގުވާވެރި ނުވަނީހެއްޔެވެ؟","",""],["","","","إني لكم رسول أمين","ހަމަކަށަވަރުން، އަހުރެންނީ ތިޔަބައިމީހުންގެ ގާތަށް ފޮނުއްވާފައިވާ އަމާނަތް ތެރި ރަސޫލަކީމެވެ.","",""],["","","","فاتقوا الله وأطيعون","ފަހެ، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ތިޔަބައިމީހުން އަހުރެންނަށް ކިޔަމަންތެރިވާށެވެ!","",""],["","","","وما أسألكم عليه من أجر إن أجري إلا على رب العالمين","އަދި އަހުރެން އެ ރަސޫލު ކަން އިއްވުމަކަށް، ތިޔަބައިމީހުންގެ ކިބައިން އުޖޫރައަކަށް ނޭދެމެވެ. އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން މެނުވީ އަހުރެންނަށް ސަވާބު ދެއްވުމެއް ނުވެތެވެ.","",""],["","","","أتتركون في ما هاهنا آمنين","މި ދުނިޔެމަތީގައިވާ ނިއުމަތް ތަކުގައި، އަމާން ކަން ލިބިގެން ތިޔަބައިމީހުން އުޅުމަށް ދޫކޮށްލައްވާނެ ހެއްޔެވެ؟","",""],["","","","في جنات وعيون","ބަގީޗާތަކާއި، ފެންއާރުތަކުގެ ތެރޭގައެވެ.","",""],["","","","وزروع ونخل طلعها هضيم","އަދި ދަނޑުތަކާއި، އޭގެ އެތްތައް ފޮޅި، މޭވާ ފައްކާވެގެންވާ ކަދުރުރުއްތަކުގެ މެދުގައެވެ.","",""],["","","","وتنحتون من الجبال بيوتا فارهين","އަދި ތިޔަބައިމީހުން ބޮޑާވެ، ފަރުބަދަ ފަރުބަދައިގައި ކަނޑައި ނަގައިގެން ގޭގެ ހަދަމުއެވެ.","",""],["","","","فاتقوا الله وأطيعون","ފަހެ، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ތިޔަބައިމީހުން އަހުރެންނަށް ކިޔަމަންތެރިވާށެވެ!","",""],["","","","ولا تطيعوا أمر المسرفين","އަދި ހައްދުފަހަނަޅައިދާ މީހުންގެ އަމުރަށް ތިޔަބައިމީހުން ކިޔަމަންތެރި ނުވާށެވެ!","",""],["","","","الذين يفسدون في الأرض ولا يصلحون","އެއުރެންނީ ބިމުގައި ފަސާދަ އުފައްދާ، އަދި އިޞްލާޙެއް ނުކުރާ މީހުންނެވެ.","",""],["","","","قالوا إنما أنت من المسحرين","އެއުރެން ދެންނެވޫއެވެ. ކަލޭގެފާނުވަނީ ޖާދޫޖެހި (ބުއްދި ގޯސްވެ) ފައިވާ މީހުންގެ ތެރެއިންކަން ކަށަވަރެވެ.","",""],["","","","ما أنت إلا بشر مثلنا فأت بآية إن كنت من الصادقين","ތިމަންމެންކަހަލަ އާދަމުގެދަރިޔެއް ކަމުގައި މެނުވީ ކަލޭގެފާނު ނުވެތެވެ. ކަލޭގެފާނު ތެދުވެރިންގެ ތެރެއިންވާނަމަ، ފަހެ، މުއުޖިޒާއެއް ގެންނަވައި ބައްލަވާށެވެ!","",""],["","","","قال هذه ناقة لها شرب ولكم شرب يوم معلوم","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. މިއޮތީ ޖަމަލެކެވެ. އެ އެއްޗަށް ބޯފެނުގެ ޙިއްޞާއެއް ވެއެވެ. އަދި ތިޔަބައިމީހުންނަށްވެސް ކަނޑައެޅި އެނގިގެންވާ ދުވަހެއްގެ ބޯފެނުގެ ޙިއްޞާއެއް ވެއެވެ.","",""],["","","","ولا تمسوها بسوء فيأخذكم عذاب يوم عظيم","އަދި ތިޔަބައިމީހުން އެ އެއެއްޗަށް އެއްވެސް ގޯނާއެއް ނުކުރާށެވެ! ފަހެ، (އެހެން ހަދައިފިނަމަ) ބޮޑުވެގެންވާ ދުވަހެއްގެ އަޒާބު އައިސް ތިޔަބައިމީހުންނަށް ޖެހިދާނެތެވެ.","",""],["","","","فعقروها فأصبحوا نادمين","ފަހެ، އެއުރެން އޭތި މަރައިލިއެވެ. ދެން ހިތާމަކުރާ ބަޔަކު ކަމުގައި އެއުރެންވޫއެވެ.","",""],["","","","فأخذهم العذاب إن في ذلك لآية وما كان أكثرهم مؤمنين","ފަހެ، އެއުރެންނަށް އަޒާބު އައިސް ޖެހުނެވެ. ހަމަކަށަވަރުން، އެކަންތަކުގައި (ﷲގެ ކުޅަދުންވަންތަކަމުގެ) ހެތްކެއްވާކަން ކަށަވަރެވެ. އަދި އެއުރެންކުރެ ގިނަމީހުން އީމާންވާ ބަޔަކު ކަމުގައި ނުވެތެވެ.","",""],["","","","وإن ربك لهو العزيز الرحيم","އަދި ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ޢަޒީޒުވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","كذبت قوم لوط المرسلين","ލޫޠުގެފާނުގެ ގައުމުގެމީހުން ރަސޫލުން ދޮގުކުރޫއެވެ.","",""],["","","","إذ قال لهم أخوهم لوط ألا تتقون","(އެއީ) އެއުރެންގެ އަޚު، ލޫޠުގެފާނު އެއުރެންނަށް ވިދާޅުވިހިނދުގައެވެ. ތިޔަބައިމީހުން (ﷲއަށް) ތަގުވާވެރި ނުވަނީ ހެއްޔެވެ؟","",""],["","","","إني لكم رسول أمين","ހަމަކަށަވަރުން، އަހުރެންނީ، ތިޔަބައިމީހުންގެ ގާތަށް ފޮނުއްވާފައިވާ އަމާނަތް ތެރި ރަސޫލަކީމެވެ.","",""],["","","","فاتقوا الله وأطيعون","ފަހެ، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ތިޔަބައިމީހުން އަހުރެންނަށް ކިޔަމަންތެރިވާށެވެ!","",""],["","","","وما أسألكم عليه من أجر إن أجري إلا على رب العالمين","އަދި އަހުރެން އެ ރަސޫލު ކަން، އިއްވުމަކަށް ތިޔަބައިމީހުންގެ ކިބައިން އުޖޫރައަކަށް ނޭދެމެވެ. އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން މެނުވީ އަހުރެންނަށް ސަވާބު ދެއްވުމެއް ނުވެތެވެ.","",""],["","","","أتأتون الذكران من العالمين","ޚަލްގު ތަކުންގެ ތެރެއިން ފިރިހެނުންނާ ތިޔަބައިމީހުން ގާތްވަނީ ހެއްޔެވެ؟","",""],["","","","وتذرون ما خلق لكم ربكم من أزواجكم بل أنتم قوم عادون","ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ތިޔަބައިމީހުންނަށްޓަކައި ހައްދަވައި (ހަލާލުކުރައްވައި) ފައިވާ އަނބިން ދޫކުރަނީ ހެއްޔެވެ؟ އަދި ކިއެއްތަ! ތިޔަބައިމީހުންނީ (ނުބައިކަންތަކުގައި) ހައްދުފަހަނަޅައިދާ ބަޔަކީމުއެވެ.","",""],["","","","قالوا لئن لم تنته يا لوط لتكونن من المخرجين","އެއުރެން ދެންނެވޫއެވެ. އޭ ލޫޠުގެފާނެވެ! ކަލޭގެފާނު (ތިމަންމެންނާ ދެކޮޅު ހެއްދެވުން) ހުއްޓަވައިނުލެއްވިނަމަ (ރަށުން) ނެރެލެވޭ މީހުންގެ ތެރެއިން ކަލޭގެފާނު ވާހުށިކަން ކަށަވަރެވެ.","",""],["","","","قال إني لعملكم من القالين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނު ވަނީ ތިޔަބައިމީހުންގެ ޢަމަލަށް (އެބަހީ: ލިވާޠުގެ ޢަމަލަށް) ރުޅިއަރާ މީހުންގެ ތެރެއިންނެވެ.","",""],["","","","رب نجني وأهلي مما يعملون","އަޅުގެ ވެރިރަސްކަލާކޮ! އެއުރެންކުރާ ޢަމަލުން މިއަޅާއާއި މިއަޅާގެ އަހުލުވެރިން ސަލާމަތް ކުރައްވާނދޭވެ!","",""],["","","","فنجيناه وأهله أجمعين","ފަހެ، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނާއި، އެކަލޭގެފާނުގެ އަހުލުވެރި އެންމެން ސަލާމަތް ކުރެއްވީމެވެ.","",""],["","","","إلا عجوزا في الغابرين","އަޒާބު ލިބުނު މީހުންގެ ތެރޭގައިވި މުސްކުޅި އަންހެނަކު މެނުވީއެވެ.","",""],["","","","ثم دمرنا الآخرين","ދެން ތިމަންރަސްކަލާނގެ (އެ ގައުމުގެ) މީހުން ހަލާކުކުރެއްވީމެވެ.","",""],["","","","وأمطرنا عليهم مطرا فساء مطر المنذرين","އަދި ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް (ހިލައިގެ) ވާރޭއެއް ވެއްސެވީމެވެ. ފަހެ، އިންޒާރުކުރައްވާފައިވާ މީހުންގެ (މައްޗަށް ވެހުނު) ވާރޭގެ ނުބައިކަމާއެވެ!","",""],["","","","إن في ذلك لآية وما كان أكثرهم مؤمنين","ހަމަކަށަވަރުން، އެކަންތަކުގައި (ﷲގެ ކުޅަދުންވަންތަކަމުގެ) ހެތްކެއްވާކަން ކަށަވަރެވެ. އަދި އެއުރެންކުރެ ގިނަމީހުން، އީމާންވާ ބަޔަކު ކަމުގައި ނުވެތެވެ.","",""],["","","","وإن ربك لهو العزيز الرحيم","އަދި ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ޢަޒީޒުވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","كذب أصحاب الأيكة المرسلين","އަލްއައިކަތުގެ އަހުލުވެރިން ރަސޫލުން ދޮގުކުރޫއެވެ.","",""],["","","","إذ قال لهم شعيب ألا تتقون","(އެއީ) އެއުރެންނަށް ޝުއައިބުގެފާނު ވިދާޅުވި ހިނދުގައެވެ. ތިޔަބައިމީހުން (ﷲއަށް) ތަގުވާވެރި ނުވަނީހެއްޔެވެ؟","",""],["","","","إني لكم رسول أمين","ހަމަކަށަވަރުން، އަހުރެންނީ ތިޔަބައިމީހުންގެ ގާތަށް ފޮނުއްވާފައިވާ އަމާނަތް ތެރި ރަސޫލަކީމެވެ.","",""],["","","","فاتقوا الله وأطيعون","ފަހެ، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ތިޔަބައިމީހުން އަހުރެންނަށް ކިޔަމަންތެރިވާށެވެ!","",""],["","","","وما أسألكم عليه من أجر إن أجري إلا على رب العالمين","އަދި އަހުރެން އެ ރަސޫލު ކަން އިއްވުމަކަށް، ތިޔަބައިމީހުންގެ ކިބައިން އުޖޫރައަކަށް ނޭދެމެވެ. އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން މެނުވީ އަހުރެންނަށް ސަވާބު ދެއްވުމެއް ނުވެތެވެ.","",""],["","","","أوفوا الكيل ولا تكونوا من المخسرين","ތިޔަބައިމީހުން (މިނާ ތަކެތި) މިނުން ފުރިހަމަ ކުރާށެވެ! އަދި (މިނުމާއި ކިރުމުގައި) އުނިކުރާ މީހުންގެ ތެރެއިން ތިޔަބައިމީހުން ނުވާށެވެ!","",""],["","","","وزنوا بالقسطاس المستقيم","އަދި ތިޔަބައިމީހުން (ކިރާ ތަކެތި) ސީދާވެގެންވާ ތިލަފަތުން ކިރާށެވެ!","",""],["","","","ولا تبخسوا الناس أشياءهم ولا تعثوا في الأرض مفسدين","އަދި ތިޔަބައިމީހުން މީސްތަކުންނަށް އެއުރެންގެ ތަކެތި އުނިނުކުރާށެވެ! އަދި ފާސިދުން ކަމުގައިވެތިބެ، ތިޔަބައިމީހުން ބިމުގައި ފަސާދަނުކުރާ ހުށިކަމެވެ!","",""],["","","","واتقوا الذي خلقكم والجبلة الأولين","އަދި ތިޔަބައިމީހުންނާއި، އިސްވެދިޔަ ޖީލުތައް ހެއްދެވި ރަސްކަލާނގެއަށް ތިޔަބައިމީހުން ތަގުވާވެރިވާށެވެ!","",""],["","","","قالوا إنما أنت من المسحرين","އެއުރެން ދެންނެވޫއެވެ. ކަލޭގެފާނުވަނީ ޖާދޫޖެހި (ބުއްދި ގޯސްވެ) ފައިވާ މީހުންގެ ތެރެއިންކަން ކަށަވަރެވެ.","",""],["","","","وما أنت إلا بشر مثلنا وإن نظنك لمن الكاذبين","އަދި ތިމަންމެންކަހަލަ އާދަމުގެދަރިޔެއް ކަމުގައި މެނުވީ، ކަލޭގެފާނު ނުވެތެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންމެން ހީކުރަނީ، ކަލޭގެފާނު ދޮގުވެރިންގެ ތެރެއިންވާ ކަމަށެވެ.","",""],["","","","فأسقط علينا كسفا من السماء إن كنت من الصادقين","ފަހެ، ކަލޭގެފާނު ތެދުވެރިންގެ ތެރެއިންވާނަމަ، ތިމަންމެންގެ މައްޗަށް އުޑުން ތަންގަނޑެއް ވައްޓަވައިލައްވަ ބައްލަވާށެވެ!","",""],["","","","قال ربي أعلم بما تعملون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ތިޔަބައިމީހުން ކުރާކަންތައް މޮޅަށް ދެނެވޮޑިގެންވެއެވެ.","",""],["","","","فكذبوه فأخذهم عذاب يوم الظلة إنه كان عذاب يوم عظيم","ފަހެ، އެއުރެން އެކަލޭގެފާނު ދޮގުކުރޫއެވެ. ދެން ވިލާގަނޑުގެ ދުވަހުގެ އަޒާބު، އެއުރެންނަށް ޖެހުނެވެ. ހަމަކަށަވަރުން، އެ އަޒާބު ވީ، ބޮޑުވެގެންވާ ދުވަހެއްގެ އަޒާބަކަށެވެ.","",""],["","","","إن في ذلك لآية وما كان أكثرهم مؤمنين","ހަމަކަށަވަރުން، އެކަންތަކުގައި (ﷲގެ ކުޅަދުންވަންތަކަމުގެ) ހެތްކެއްވާކަން ކަށަވަރެވެ. އަދި އެއުރެންކުރެ ގިނަމީހުން އީމާންވާ ބަޔަކު ކަމުގައި ނުވެތެވެ.","",""],["","","","وإن ربك لهو العزيز الرحيم","އަދި ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ޢަޒީޒުވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","وإنه لتنزيل رب العالمين","ހަމަކަށަވަރުން، އެ ގުރްއާނަކީ، އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ބާވައިލެއްވި ފޮތެއްކަން ކަށަވަރެވެ.","",""],["","","","نزل به الروح الأمين","ކަލޭގެފާނުގެ ހިތްޕުޅުގެ މައްޗަށް އެ ގުރްއާނާއިގެން ފައިބައިވަޑައިގަތީ، ޖިބްރީލުގެފާނެވެ. އެއީ (މީސްތަކުންނަށް) އިންޒާރުކުރައްވާ ބޭކަލުންގެ ތެރެއިން ކަލޭގެފާނު ވެވަޑައިގަތުމަށެވެ.","",""],["","","","على قلبك لتكون من المنذرين","ކަލޭގެފާނުގެ ހިތްޕުޅުގެ މައްޗަށް އެ ގުރްއާނާއިގެން ފައިބައިވަޑައިގަތީ، ޖިބްރީލުގެފާނެވެ. އެއީ (މީސްތަކުންނަށް) އިންޒާރުކުރައްވާ ބޭކަލުންގެ ތެރެއިން ކަލޭގެފާނު ވެވަޑައިގަތުމަށެވެ.","",""],["","","","بلسان عربي مبين","(އެ ގުރްއާން ބާވައިލެއްވީ) ބަޔާން ވެގެންވާ އަރަބި ބަހުންނެވެ.","",""],["","","","وإنه لفي زبر الأولين","އަދި ހަމަކަށަވަރުން، އިސްވެދިޔަ ނަބިއްޔުންގެ ފޮތްތަކުގައިވެސް އެ ގުރްއާންގެ ވާހަކަ ވާކަން ކަށަވަރެވެ.","",""],["","","","أولم يكن لهم آية أن يعلمه علماء بني إسرائيل","އިސްރާއީލުގެދަރިންކުރެ، އިލްމުވެރިން އެކަންތައް ދަންނަކަން އެއީ، އެއުރެންނަށް (އެބަހީ: މައްކާގެ މުޝްރިކުންނަށް) ހެތްކެއްކަމުގައި ނުވޭހެއްޔެވެ؟","",""],["","","","ولو نزلناه على بعض الأعجمين","އަދި ޢަޖަމީންގެ މީހެއްގެ މައްޗަށް ތިމަންރަސްކަލާނގެ އެ ގުރްއާން ބާވައިލައްވައި، ދެން އެމީހަކު އެ ގުރްއާން އެމީހުންނަށް ކިޔައިދިންނަމަވެސް، އެއުރެން، އެއަށް އީމާންވާ ބަޔަކު ކަމުގައި ނުވީހެވެ.","",""],["","","","فقرأه عليهم ما كانوا به مؤمنين","އަދި ޢަޖަމީންގެ މީހެއްގެ މައްޗަށް ތިމަންރަސްކަލާނގެ އެ ގުރްއާން ބާވައިލައްވައި، ދެން އެމީހަކު އެ ގުރްއާން އެމީހުންނަށް ކިޔައިދިންނަމަވެސް، އެއުރެން، އެއަށް އީމާންވާ ބަޔަކު ކަމުގައި ނުވީހެވެ.","",""],["","","","كذلك سلكناه في قلوب المجرمين","ތިމަންރަސްކަލާނގެ އެފަދައިން ކުށްވެރިންގެ ހިތްތަކަށް ދޮގުކުރުން ވެއްދެވީމެވެ.","",""],["","","","لا يؤمنون به حتى يروا العذاب الأليم","ވޭންދެނިވި އަޒާބެއުރެންނަށް ފެނިއްޖައުމަށްދާނދެން އެއުރެން އެއަކަށް އީމާނެއް ނުވާނެތެވެ.","",""],["","","","فيأتيهم بغتة وهم لا يشعرون","ފަހެ، އެއުރެންނަށް ނުވެސް އެނގިތިއްބައި، އެ އަޒާބެއުރެންގެ ގާތަށް އަންނާނީ ކުއްލިއަކަށެވެ.","",""],["","","","فيقولوا هل نحن منظرون","ފަހެ، އެއުރެން ބުނާނެތެވެ. (އީމާން ވުމަށްޓަކައި) ތިމަންމެންނަށް ލަސްކޮށްލައްވާނެ ހެއްޔެވެ؟","",""],["","","","أفبعذابنا يستعجلون","ފަހެ، އެއުރެން އަވަސްވުން އެދެނީ، ތިމަންރަސްކަލާނގެ އަޒާބަށް ހެއްޔެވެ؟","",""],["","","","أفرأيت إن متعناهم سنين","ފަހެ، ކަލޭގެފާނަށް އެނގިވަޑައިގަންނަވާތޯއެވެ؟ ތިމަންރަސްކަލާނގެ އެއުރެން އެތައް އަހަރަކަށް އަރާމުކޮށް އުޅުމަށް ލެހެއްޓެވިކަމުގައިވިޔަސް، ދެން އެއުރެންނަށް ވައުދުކުރައްވާފައިވާ އަޒާބެއުރެންގެ ގާތަށް އައުމުން، އެއުރެން ދުނިޔޭގައި އަރާމުކޮށް އުޅުމަށް ލެހެއްޓެވުމަކުން އެއުރެންނަށް އެއްވެސްކަމެއް ފުއްދައެއް ނުދޭނެތެވެ.","",""],["","","","ثم جاءهم ما كانوا يوعدون","ފަހެ، ކަލޭގެފާނަށް އެނގިވަޑައިގަންނަވާތޯއެވެ؟ ތިމަންރަސްކަލާނގެ އެއުރެން އެތައް އަހަރަކަށް އަރާމުކޮށް އުޅުމަށް ލެހެއްޓެވިކަމުގައިވިޔަސް، ދެން އެއުރެންނަށް ވައުދުކުރައްވާފައިވާ އަޒާބެއުރެންގެ ގާތަށް އައުމުން، އެއުރެން ދުނިޔޭގައި އަރާމުކޮށް އުޅުމަށް ލެހެއްޓެވުމަކުން އެއުރެންނަށް އެއްވެސްކަމެއް ފުއްދައެއް ނުދޭނެތެވެ.","",""],["","","","ما أغنى عنهم ما كانوا يمتعون","ފަހެ، ކަލޭގެފާނަށް އެނގިވަޑައިގަންނަވާތޯއެވެ؟ ތިމަންރަސްކަލާނގެ އެއުރެން އެތައް އަހަރަކަށް އަރާމުކޮށް އުޅުމަށް ލެހެއްޓެވިކަމުގައިވިޔަސް، ދެން އެއުރެންނަށް ވައުދުކުރައްވާފައިވާ އަޒާބެއުރެންގެ ގާތަށް އައުމުން، އެއުރެން ދުނިޔޭގައި އަރާމުކޮށް އުޅުމަށް ލެހެއްޓެވުމަކުން އެއުރެންނަށް އެއްވެސްކަމެއް ފުއްދައެއް ނުދޭނެތެވެ.","",""],["","","","وما أهلكنا من قرية إلا لها منذرون","އެއްވެސް ރަށެއް، އެރަށުގެ އަހުލުވެރިންނަށް އިންޒާރުކުރައްވާނޭ ރަސޫލުން ނުފޮނުއްވައެއް ތިމަންރަސްކަލާނގެ ހަލާކެއް ނުކުރައްވަމެވެ.","",""],["","","","ذكرى وما كنا ظالمين","(އެއީ) ހަނދާންކޮށްދެއްވުމެކެވެ. އަދި އަނިޔާވެރި ކަލަކު ކަމުގައި ތިމަންރަސްކަލާނގެ ނުވަމެވެ.","",""],["","","","وما تنزلت به الشياطين","އެ ގުރްއާންގެނެސްދިނީ ޝައިތާނުންނެއް ނޫނެވެ.","",""],["","","","وما ينبغي لهم وما يستطيعون","އަދި އެއީ ޝައިތާނުންނަށް އެކަށީގެންވާ ކަމެއްނޫނެވެ. އަދި އެ ޝައިތާނުންނަށް އެކަމަކަށް ކުޅަދާނަވެގެނެއްވެސް ނުވެއެވެ.","",""],["","","","إنهم عن السمع لمعزولون","ހަމަކަށަވަރުން، އެ ޝައިތާނު ންވަނީ (ވަގަށް) އަޑުއެހުމުން ވަކިކުރައްވާފައިކަން ކަށަވަރެވެ.","",""],["","","","فلا تدع مع الله إلها آخر فتكون من المعذبين","ފަހެ، ﷲއާއެކު އެހެން އިލާހަކަށް ކަލޭގެފާނު ދުއާކުރައްވައި، އަޅުކަން ނުކުރައްވާށެވެ! ފަހެ، އޭރުން އަޒާބު ލިބޭ މީހުންގެ ތެރެއިން ކަލޭގެފާނު ވެދާނެއެވެ.","",""],["","","","وأنذر عشيرتك الأقربين","ކަލޭގެފާނުގެ އެންމެ ގާތްތިމާގެ ގަބީލާގެ މީހުންނަށް އިންޒާރުކުރައްވާށެވެ!","",""],["","","","واخفض جناحك لمن اتبعك من المؤمنين","މުއުމިނުންގެ ތެރެއިން ކަލޭގެފާނަށް ތަބާ ވީ މީހުންނަށް، ކަލޭގެފާނުގެ ފިޔަފުޅު ތިރިކުރައްވާށެވެ! (އެބަހީ: މަޑުމައިތިރިވެވަޑައިގަންނަވާށެވެ!)","",""],["","","","فإن عصوك فقل إني بريء مما تعملون","ފަހެ، އެއުރެން ކަލޭގެފާނަށް އުރެދިއްޖެނަމަ، ފަހެ، ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންކުރާ ޢަމަލު ތަކުން ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނު ބަރީއަވެގެންވަމެވެ.","",""],["","","","وتوكل على العزيز الرحيم","އަދި ޢަޒީޒުވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެއަށް ކަލޭގެފާނު ވަކީލުކުރައްވާށެވެ!","",""],["","","","الذي يراك حين تقوم","އެކަލާނގެއީ، ކަލޭގެފާނު (ނަމާދަށް) ތެދުވެވަޑައިގަންނަވާހިނދު، ކަލޭގެފާނު ދެކެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وتقلبك في الساجدين","އަދި ސަޖިދަ ކޮށް ނަމާދުކުރާ މީހުންގެ ތެރޭގައި ކަލޭގެފާނު ޙަރަކާތް ތެރިވެ ވަޑައިގަންނަވާތީވެސްމެއެވެ.","",""],["","","","إنه هو السميع العليم","ހަމަކަށަވަރުން، އެކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","هل أنبئكم على من تنزل الشياطين","އެއުރެންގެ މައްޗަށް ޝައިތާނުން ފައިބާ މީހުންގެ ޚަބަރު، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް ދެއްވަން ހެއްޔެވެ؟","",""],["","","","تنزل على كل أفاك أثيم","އެ ޝައިތާނުން ފައިބަނީ، ދޮގުވެރިކަން ބޮޑު، ފާފަވެރިކަން ބޮޑު ކޮންމެ މީހެއްގެ މައްޗަށެވެ.","",""],["","","","يلقون السمع وأكثرهم كاذبون","އެ ޝައިތާނުން އަޑުއަހާ ތަކެތި (ކާހިނުންނަށް) ލައިދެތެވެ. އަދި އޭގެ ގިނަމީހުންނީ، ދޮގުވެރިންނެވެ.","",""],["","","","والشعراء يتبعهم الغاوون","ޅެންވެރިންނަށް (އެބަހީ: އެއުރެންގެ ތެރެއިން ކާފިރުންނަށް) ތަބާ ވާނީ މަގުފުރެދިގެންވާ މީހުންނެވެ.","",""],["","","","ألم تر أنهم في كل واد يهيمون","ހަމަކަށަވަރުން، (ބަހުގެ) ކޮންމެ ވާދީއެއްގައިމެ، ދެވޭނުދެވޭ ތަނެއް ނޭނގޭގޮތަށް، އެއުރެން އުޅޭތީ ކަލޭގެފާނު ދެކެވަޑައިނުގަންނަވަމުތޯއެވެ؟","",""],["","","","وأنهم يقولون ما لا يفعلون","އަދި ހަމަކަށަވަރުން، އެއުރެން ބުނެއުޅެނީ، އެއުރެން ނުކުރާ ކަންތަކުގެ ވާހަކައެވެ.","",""],["","","","إلا الذين آمنوا وعملوا الصالحات وذكروا الله كثيرا وانتصروا من بعد ما ظلموا وسيعلم الذين ظلموا أي منقلب ينقلبون","އީމާންވެ ސާލިހު ޢަމަލުތައްކޮށް، އަދި ގިނަގިނައިން ﷲ ހަނދުމަކޮށް، އަދި އަނިޔާލިބުމަށްފަހު، ނަސްރު ލިބިގަތްމީހުން މެނުވީއެވެ. ނިކަންހުރެ އަނިޔާވެރިވި މީހުންނަށް، އެއުރެން ރުޖޫއަ ވާހުށީ ކޮންތަނަކަށްކަން އެނގޭހުށްޓެވެ.","",""],["","","","بسم الله الرحمن الرحيم طس تلك آيات القرآن وكتاب مبين","ط س (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.) މިއީ ކީރިތި ގުރްއާންގެ އަދި ބަޔާންވެގެންވާ ފޮތެއްގެ އާޔަތް ތަކެވެ. (އެބަހީ: ބަޔާންވެގެންވާ ފޮތެއްކަމުގައިވާ ގުރްއާންގެ އާޔަތް ތަކެވެ.)","",""],["","","","هدى وبشرى للمؤمنين","(އެއީ) މުއުމިނުންނަށް ތެދުމަގެކެވެ. އަދި އުފާވެރި ޚަބަރެއްމެއެވެ.","",""],["","","","الذين يقيمون الصلاة ويؤتون الزكاة وهم بالآخرة هم يوقنون","އެއުރެންނީ ނަމާދު ގާއިމު ކޮށް، ޒަކާތް ދީ، އަދި އާޚިރަތް ދުވަހާމެދު ޔަގީންކުރާ މީހުންނެވެ.","",""],["","","","إن الذين لا يؤمنون بالآخرة زينا لهم أعمالهم فهم يعمهون","ހަމަކަށަވަރުން، އާޚިރަތް ދުވަހަށް އީމާން ނުވާ މީހުންނަށް ތިމަންރަސްކަލާނގެ އެއުރެންގެ ޢަމަލުތައް ޒީނަތްތެރި ކުރެއްވީމެވެ. ފަހެ، އެއުރެންވަނީ ހައިރާންވެ، ދެފުށުއެޅޭ ޙާލު ގައެވެ.","",""],["","","","أولئك الذين لهم سوء العذاب وهم في الآخرة هم الأخسرون","އެއުރެންނީ އެއުރެންނަށް ނުބައިވެގެންވާ އަޒާބު ހުރި މީހުންނެވެ. އަދި އެއުރެންނީ އާޚިރަތުގައި ހަމައެންމެ ގެއްލެނިވެގެންވާ މީހުންނެވެ.","",""],["","","","وإنك لتلقى القرآن من لدن حكيم عليم","ހަމަކަށަވަރުން، ކަލޭގެފާނަށް ގުރްއާން އުނގަންނައިދެއްވަނީ، ޙަކީމްވަންތަ، މޮޅަށް ދެނެވޮޑިގެންވާ ކަލެއްގެ ހަޒުރަތު ންކަން ކަށަވަރެވެ.","",""],["","","","إذ قال موسى لأهله إني آنست نارا سآتيكم منها بخبر أو آتيكم بشهاب قبس لعلكم تصطلون","މޫސާގެފާނު އެކަލޭގެފާނުގެ އަހުލުވެރިންނަށް ވިދާޅުވިހިނދު ހަނދުމަކުރާށެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނަށް އަލިފާންގަނޑެއް ފެނިއްޖެއެވެ. ތިމަންކަލޭގެފާނު އެތަނުން ޚަބަރަކާއިގެން ތިޔަބައިމީހުންގެ ގާތަށް ވަޑައިގަންނަވާހުށީމެވެ. ނުވަތަ ތިޔަބައިމީހުން ހީފިލުވުމަށް ހުޅުކޮޅެއް ގެންނަވާހުށީމެވެ.","",""],["","","","فلما جاءها نودي أن بورك من في النار ومن حولها وسبحان الله رب العالمين","ފަހެ، މޫސާގެފާނު އެ އަލިފާންގަނޑުގެ ކައިރިޔަށް ވަޑައިގަތްހިނދު އެކަލޭގެފާނަށް ނިދާއިއްވެވިއެވެ. އަލިފާންގަނޑުގެ ކައިރީގައިވާ މީހަކަށާއި (އެބަހީ: މޫސާގެފާނަށާއި) އަލިފާންގަނޑުގެ ވަށައިގެންވާ ބަޔަކަށް (އެބަހީ: މަލާއިކަތުންނަށް) ބަރަކާތް ލައްވާފައިވެއެވެ. އާލަމްތަކުގެ ވެރި ﷲ، ހުސްތާހިރު ވަންތަވެވޮޑިގެންވެއެވެ.","",""],["","","","يا موسى إنه أنا الله العزيز الحكيم","އޭ މޫސާގެފާނެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ﷲއެވެ.","",""],["","","","وألق عصاك فلما رآها تهتز كأنها جان ولى مدبرا ولم يعقب يا موسى لا تخف إني لا يخاف لدي المرسلون","އަދި ކަލޭގެފާނުގެ އަސާކޮޅު އެއްލަވާށެވެ! ފަހެ، އެ އަސާކޮޅު (އެއްލެވީމާ) ހަރުފަޔެއްހެން ހެލިފެލިވާތީ، ފެނިވަޑައިގަތްހިނދު (ބިރުފުޅުން) ފުރަގަސްދެއްވައި ދުވެވަޑައިގަތެވެ. އަދި އެނބުރި ވަޑައެއްނުގަތެވެ. (ދެން ވަހީކުރެއްވިއެވެ.) އޭ މޫސާގެފާނެވެ! ކަލޭގެފާނު ބިރުފުޅު ނުގަންނާށެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ހަޒުރަތުގައި ރަސޫލުން (އެއްވެސް އެއްޗެއް ދެކެ) ބިރުފުޅެއް ނުގަންނާނެތެވެ.","",""],["","","","إلا من ظلم ثم بدل حسنا بعد سوء فإني غفور رحيم","އެހެނެއްކަމަކު، އަނިޔާވެރިވެ، ނުބައިކަމެއް ކުރުމަށްފަހު، އޭގެބަދަލުގައި ރަނގަޅުކަމެއްކޮށްފި މީހަކަށް، ފަހެ، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وأدخل يدك في جيبك تخرج بيضاء من غير سوء في تسع آيات إلى فرعون وقومه إنهم كانوا قوما فاسقين","އަދި ކަލޭގެފާނު ހެދުންކޮޅުގެ މަންސަފާއަށް އަތްޕުޅު ލައްވާށެވެ! އެއްވެސް ބަލިމަޑުކަމެއްގެ ނުބަޔަކާނުލައި، ހުދުކޮށް (ވިދަވިދާ އޮންނަގޮތުގައި) އެ އަތްޕުޅު ނުކުންނާނެތެވެ. ފިރްޢައުނާއި، އޭނާގެ ގައުމުގެމީހުންނަށް ފޮނުއްވި ނުވަ މުއުޖުޒާތްގެ ތެރެއިންނެވެ. ހަމަކަށަވަރުން، ފާސިގު ބަޔަކުކަމުގައި، އެއުރެންވޫއެވެ.","",""],["","","","فلما جاءتهم آياتنا مبصرة قالوا هذا سحر مبين","ފަހެ، ތިމަންރަސްކަލާނގެ މުއުޖުޒާތްތައް ފާޅުވެގެންވާ ޙާލުގައި އެއުރެންގެ ގާތަށް އައިހިނދު، އެއުރެން ބުނެފޫއެވެ. މިއީ ފާޅުވެގެންވާ ޖާދޫއެކެވެ.","",""],["","","","وجحدوا بها واستيقنتها أنفسهم ظلما وعلوا فانظر كيف كان عاقبة المفسدين","އަދި އެ އާޔަތްތައް އެއީ، ތެދުކަން އެއުރެންގެ ނަފްސުތަކަށް ޔަގީން ވެތިބެ، އަނިޔާވެރިކަމާއި، ބޮޑާވެގަތުމުގެ ގޮތުން، އެ އާޔަތްތަކަށް އެއުރެން އިންކާރުކުރޫއެވެ. ފަހެ، ފަސާދަކުރާމީހުންގެ ނިމުންވަނީ ކިހިނަކުންކަން، ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާށެވެ!","",""],["","","","ولقد آتينا داوود وسليمان علما وقالا الحمد لله الذي فضلنا على كثير من عباده المؤمنين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ދާވޫދުގެފާނާއި، ސުލައިމާނުގެފާނަށް އިލްމުވެރިކަން ދެއްވީމެވެ. އަދި އެ ދެބޭކަލުން ވިދާޅުވިއެވެ. ހަމްދު ހުރީ ﷲއަށެވެ. އެކަލާނގެއީ، އެކަލާނގެއަށް އީމާން ވެގެންވާ އަޅުންގެ ތެރެއިން، ގިނަމީހުންގެ މައްޗަށް ތިމަންމެން މާތްކުރެއްވި ރަސްކަލާނގެއެވެ.","",""],["","","","وورث سليمان داوود وقال يا أيها الناس علمنا منطق الطير وأوتينا من كل شيء إن هذا لهو الفضل المبين","އަދި ދާވޫދުގެފާނުގެ ކިބައިން (ނަބީކަމާއި ވެރިކަން) ވާރުތަވީ، ސުލައިމާނުގެފާނަށެވެ. އަދި އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ މީސްތަކުންނޭވެ! އަހުރެމެންނަށް ދޫނިސޫފާސޫފީގެ ބަހުރުވަ އުނގަންނައިދެއްވިއެވެ. އަދި އަހުރެމެންނަށް ހުރިހާކަމެއް ލިބިފައިވެއެވެ. ހަމަކަށަވަރުން، މިކަންތަކަކީ، ފާޅުވެ އެނގިގެންވާ ފަޟްލުވަންތަ ކަމެއްކަން ކަށަވަރެވެ.","",""],["","","","وحشر لسليمان جنوده من الجن والإنس والطير فهم يوزعون","އަދި ޖިންނީންނާއި، އިންސީންނާއި، ދޫނިސޫފާސޫފީގެ ތެރެއިން ސުލައިމާނުގެފާނަށް އެކަލޭގެފާނުގެ ލަޝްކަރެއްކުރެއްވުނެވެ. ފަހެ، އެ ލަޝްކަރު އެތުރިގެންވެއެވެ.","",""],["","","","حتى إذا أتوا على واد النمل قالت نملة يا أيها النمل ادخلوا مساكنكم لا يحطمنكم سليمان وجنوده وهم لا يشعرون","(ދެން ލަޝްކަރާއިގެން) ހިނީގެ ވާދީއަށް ވަޑައިގެންފުމަށް ދާނދެނެވެ. އެހިނދު ހިންޏެއް ބުންޏެވެ. އޭ ހިނިތަކާއެވެ! ކަލޭމެންގެ ގޭގެއަށް ވަންނާށެވެ! (އެއީ) ނޭނގިތިބެ، ސުލައިމާނުގެފާނާއި، އެކަލޭގެފާނުގެ ލަޝްކަރު ކަލޭމެން ފިސްފިސް ނުކުރުމަށްޓަކައެވެ.","",""],["","","","فتبسم ضاحكا من قولها وقال رب أوزعني أن أشكر نعمتك التي أنعمت علي وعلى والدي وأن أعمل صالحا ترضاه وأدخلني برحمتك في عبادك الصالحين","ފަހެ (ސުލައިމާނުގެފާނު) އެ ހިނި ބުނިވާހަކަ އައްސަވައި ހިނިފުޅުވެޑުވިއެވެ. އަދި ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޯއެވެ! އިބަރަސްކަލާނގެ މިއަޅާގެ މައްޗަށާއި، މިއަޅާގެ މައިންބަފައިންގެ މައްޗަށް ދެއްވި ނިއުމަތަށް ޝުކުރުކުރުމަށާއި، އިބަރަސްކަލާނގެ ރުހިވޮޑިގެންވާ ސާލިހު ޢަމަލުކުރުމަށް މިއަޅާއަށް އިލްހާމްކުރައްވާނދޭވެ! އަދި އިބަރަސްކަލާނގެ ރަހުމަތްފުޅުން، އިބަރަސްކަލާނގެ ސާލިހު އަޅުންގެ ތެރެއިން މިއަޅާ ލައްވާނދޭވެ!","",""],["","","","وتفقد الطير فقال ما لي لا أرى الهدهد أم كان من الغائبين","އަދި އެކަލޭގެފާނު ދޫނިސޫފާސޫފި ހޯއްދަވައި ބެއްލެވިއެވެ. ފަހެ، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަހުރެންނަށް ހުދުހުދު މި ނުފެންނަނީ ކީއްވެގެން ހެއްޔެވެ؟ ނުވަތަ އޭތި ޣައިބު ވެގެންވީ ހެއްޔެވެ؟","",""],["","","","لأعذبنه عذابا شديدا أو لأذبحنه أو ليأتيني بسلطان مبين","ހަމަކަށަވަރުން، (އޭތީގެ ޢުޛުރެއްގެގޮތުން) ފާޅުވެގެންވާ ހެތްކެއް އަހުރެންގެގާތަށް ނުގެނައިނަމަ، އެ އެއްޗަށް ބޮޑުވެގެންވާ އުގޫބާތެއް އަހުރެން ދޭހުށީމެވެ. ނުވަތަ އޭތި ކަތިލާހުށީމެވެ.","",""],["","","","فمكث غير بعيد فقال أحطت بما لم تحط به وجئتك من سبإ بنبإ يقين","ފަހެ، އެ ދޫނި މާދުރުނޫން ތަނެއްގައި ކުޑައިރުކޮޅެއްވަންދެން އުޅެފައި (އަތުވެއްޖެއެވެ.) ދެން އޭތި ދެންނެވިއެވެ. ކަލޭގެފާނަށް އެނގިވަޑައިގެންނުވާ ކަންތައްތަކެއް ތިމަންނާއަށް އެނގިއްޖެއެވެ. ކަލޭގެފާނުގެ އަރިހަށް ތިމަންމިއައީ، (ޔަމަނު ކަރައިގެ) ސަބާ އިން ޔަގީން ވެގެންވާ ޚަބަރަކާއިގެންނެވެ.","",""],["","","","إني وجدت امرأة تملكهم وأوتيت من كل شيء ولها عرش عظيم","އެތާނގެ މީހުންގެ މައްޗަށް ރަނިކަންކުރައްވާ ކަމަނާއަކު ހަމަކަށަވަރުން، ތިމަންދުށީމެވެ. ހުރިހާ އެއްޗެއް އެކަމަނާއަށް ލިބިވަޑައިގެންފައިވެއެވެ. އަދި އެކަމަނާއަށް ބޮޑުވެގެންވާ ތަޚުތެއް ވެއެވެ.","",""],["","","","وجدتها وقومها يسجدون للشمس من دون الله وزين لهم الشيطان أعمالهم فصدهم عن السبيل فهم لا يهتدون","އެކަމަނާއާއި، އެކަމަނާގެ ގައުމުގެމީހުން، ﷲ ފިޔަވައި އިރަށް ސަޖިދަ ކޮށް އުޅޭތީ ތިމަންދުށީމެވެ. އަދި ޝައިތާނާ އެއުރެންނަށް އެއުރެންގެ ޢަމަލުތައް ޒީނަތްތެރިކޮށް ދެއްކިއެވެ. އަދި ތެދުމަގުން އެއުރެން އެއްކިބާކުރިއެވެ. ފަހެ، އެއުރެންނަކަށް ތެދުމަގެއް ނުލިބެއެވެ.","",""],["","","","ألا يسجدوا لله الذي يخرج الخبء في السماوات والأرض ويعلم ما تخفون وما تعلنون","އުޑުތަކާއި، ބިމުގައި ފޮރުވިފައިވާ ތަކެތި ނެރުއްވާ، އަދި ތިޔަބައިމީހުން ވަންހަނާކުރާ ކަންތަކާއި، ފާޅުކުރާ ކަންތައް ދެނެވޮޑިގެންވާ ﷲއަށް ސަޖިދަ ނުކުރުމަށް ޝައިތާނާ އެއުރެންނަށް ޒީނަތްތެރިކޮށްދިނެވެ.","",""],["","","","الله لا إله إلا هو رب العرش العظيم","ﷲއީ، އެކަލާނގެ ފިޔަވައި ހައްގު ވެގެން އަޅުކަމެއްވެވޭ އިލާހަކު ނުވާ ރަސްކަލާނގެއެވެ. އެއީ މާތްވެގެންވާ ޢަރްޝުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["","","","قال سننظر أصدقت أم كنت من الكاذبين","އެކަލޭގެފާނު (ހުދުހުދަށް) ވިދާޅުވިއެވެ. ކަލޭ ތިޔަބުނީ ތެދެއްތޯ ނުވަތަ ކަލޭވަނީ ދޮގުވެރިންގެ ތެރެއިންތޯ ތިމަންކަލޭގެފާނު ބައްލަވާހުށީމެވެ.","",""],["","","","اذهب بكتابي هذا فألقه إليهم ثم تول عنهم فانظر ماذا يرجعون","އަހުރެންގެ މި ސިޓީ ހިފައިގެންގޮސް އެއުރެންގެ ގާތަށް އެ އެއްލާށެވެ! ދެން އެއުރެންނާ ދުރަށްޖެހި (ޖަވާބުގައި) އެއުރެން ރައްދުކުރަނީ ކޮންއެއްޗެއްތޯ ބަލާށެވެ!","",""],["","","","قالت يا أيها الملأ إني ألقي إلي كتاب كريم","(ސިޓީ ލިބުމުން) އެކަމަނާ ވިދާޅުވިއެވެ. އޭ ގައުމުގެ ބޮޑުންނޭވެ! ހަމަކަށަވަރުން، މާތްވެގެންވާ ސިޓީފުޅެއް ތިމަންކަމަނާއަށް ލިބިއްޖެއެވެ.","",""],["","","","إنه من سليمان وإنه بسم الله الرحمن الرحيم","އެއީ، ހަމަކަށަވަރުން، ސުލައިމާނުގެފާނުގެ އަރިހުން އައި ސިޓީފުޅެކެވެ. އަދި ހަމަކަށަވަރުން، އޭގައި އަންގަވާފައިވަނީ [بسم ﷲ الرّحمن الرّحيم] އެވެ. (ރަޙްމާންވަންތަ ރަޙީމްވަންތަ ﷲގެ އިސްމުފުޅުން ފަށައިގަންނަމެވެ.)","",""],["","","","ألا تعلوا علي وأتوني مسلمين","ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނުގެ މައްޗަށް ބޮޑާވެނުގަނެ، އިސްލާމް ވެގެން ތިމަންކަލޭގެފާނުގެ އަރިހަށް އަންނާށެވެ!","",""],["","","","قالت يا أيها الملأ أفتوني في أمري ما كنت قاطعة أمرا حتى تشهدون","އެކަމަނާ ވިދާޅުވިއެވެ. އޭ (ގައުމުގެ) ބޮޑުންނޭވެ! އަހުރެންގެ މިކަންތަކުގައި ތިޔަބައިމީހުންނަށް ފެންނަގޮތް އަހުރެންނަށް ބުނެދޭށެވެ! ތިޔަބައިމީހުން އަހުރެންނާއެކު ޙާޒިރުު ވެއްޖައުމަށްދާނދެން އަހުރެން ގޮތެއް ކަނޑައެއް ނާޅާނަމެވެ.","",""],["","","","قالوا نحن أولو قوة وأولو بأس شديد والأمر إليك فانظري ماذا تأمرين","އެއުރެން (އެކަމަނާއަށް) ދެންނެވޫއެވެ. ތިމަންމެންނީ، އާރާއި ބާރުހުރި ގަދަފަދަ ބަޔެކެވެ. ކަންތައް ކުރައްވާނެގޮތް އެނގިވަޑައިގަންނަވާނީ ކަމަނާއަށެވެ. ފަހެ، ކަމަނާ ކުރައްވާނެ އަމުރަކާމެދު ވިސްނަވާށެވެ!","",""],["","","","قالت إن الملوك إذا دخلوا قرية أفسدوها وجعلوا أعزة أهلها أذلة وكذلك يفعلون","އެކަމަނާ ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ރަސްރަސްކަލުން (ހަނގުރާމަވެރި ގޮތުގައި) ރަށަކަށް އަރައިވަޑައިގެންފިނަމަ، އެރަށެއް ސުންނާފަތިކުރައްވައި، ފަސާދަކުރައްވައި، އަދި އެރަށެއްގެ އަހުލުވެރިންކުރެ ޢިއްޒަތް ތެރިން ނިކަމެތިކުރައްވަތެވެ. އަދި އެއުރެން ކަންތައްކުރައްވަނީ އެފަދައިންނެވެ.","",""],["","","","وإني مرسلة إليهم بهدية فناظرة بم يرجع المرسلون","އަދި ހަމަކަށަވަރުން، ތިމަންކަމަނާ އެއުރެންނަށް ހަދިޔާއެއް މިފޮނުއްވަނީއެވެ. ދެން (އެ ހަދިޔާއާއިގެން) ފޮނުވޭމީހުން އެނބުރި އަންނަނީ ކޮންއެއްޗަކާއިގެންތޯ ބައްލަވަން ތިމަންކަމަނާ އިންތިޒާރުކުރައްވާނަމެވެ.","",""],["","","","فلما جاء سليمان قال أتمدونن بمال فما آتاني الله خير مما آتاكم بل أنتم بهديتكم تفرحون","ފަހެ (އެކަމަނާ ފޮނުއްވި) މީހުން ސުލައިމާނުގެފާނުގެ އަރިހަށް އައިހިނދު، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނަށް މުދަލުން މަދަދުކުރަނީ ހެއްޔެވެ؟ ފަހެ، ﷲ ތިޔަބައިމީހުންނަށް ދެއްވާފައިވާ ތަކެއްޗަށްވުރެ، ތިމަންކަލޭގެފާނަށް ﷲ ދެއްވާފައިވާ ތަކެތި (އެބަހީ: ނަބީކަމާއި ރަސްކަން) މާހެޔޮކަން ބޮޑެވެ. އަދި ކިއެއްތަ! ތިޔަބައިމީހުންގެ ހަދިޔާއަށް އުފާކުރާނީ ހަމަތިޔަބައިމީހުންނެވެ.","",""],["","","","ارجع إليهم فلنأتينهم بجنود لا قبل لهم بها ولنخرجنهم منها أذلة وهم صاغرون","ތިޔަ ހަދިޔާއާއިގެން އެއުރެންގެ ގާތަށް އެނބުރިދާށެވެ! ފަހެ، އެއުރެންނަށް ދެކޮޅުހެދުމަށް ކުޅަދާނަވެގެންނުވާފަދަ ލަޝްކަރަކާއިގެން އެއުރެންގެ ގާތަށް ހަމަކަށަވަރުން، އަހުރެމެން ދާހުށީމުއެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެން ދެރަވެ، ނިކަމެތިވެގެންވާ ޙާލުގައި، އެރަށުން އެއުރެން ބޭރުކުރާހުށީމުއެވެ.","",""],["","","","قال يا أيها الملأ أيكم يأتيني بعرشها قبل أن يأتوني مسلمين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ ބޮޑުންނޭވެ! އެއުރެން ބޯލަނބައި ކިޔަމަންވެ، އިސްލާމް ވެގެން ތިމަންކަލޭގެފާނުގެ އަރިހަށް އައުމުގެ ކުރީގައި، އެކަމަނާގެ ތަޚުތު ތިމަންކަލޭގެފާނުގެ އަރިހަށް ގެނެސްދޭނީ، ތިޔަބައިމީހުންގެ ތެރެއިން ކާކުހެއްޔެވެ؟","",""],["","","","قال عفريت من الجن أنا آتيك به قبل أن تقوم من مقامك وإني عليه لقوي أمين","ޖިންނީންގެ ތެރެއިން ޢިފްރީތަކު ދެންނެވިއެވެ. ކަލޭގެފާނު ތިޔަ އިންނެވިތަނުން ތެދުވެވަޑައިގަތުމުގެ ކުރިން، ކަލޭގެފާނުގެ އަރިހަށް ތިމަން އެ ގެނެސްދީފާނަމެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންނާއީ، އެ އުފުލޭފަދަ، ބާރުގަދަ، އޭގެމައްޗަށް އަމާނަތް ތެރިއަކީމެވެ.","",""],["","","","قال الذي عنده علم من الكتاب أنا آتيك به قبل أن يرتد إليك طرفك فلما رآه مستقرا عنده قال هذا من فضل ربي ليبلوني أأشكر أم أكفر ومن شكر فإنما يشكر لنفسه ومن كفر فإن ربي غني كريم","(ބާވައިލެއްވި) ފޮތުން އިލްމު ލިބިފައިވާމީހާ ދެންނެވިއެވެ. ކަލޭގެފާނު ކަޅިހިންގަވައިލެއްވުމުގެ ކުރިން، ކަލޭގެފާނުގެ އަރިހަށް ތިމަން އެ ގެނެސްދީފާނަމެވެ. ދެން އެކަލޭގެފާނުގެ އަރިހުގައި އެ ތަޚުތު ބެހެއްޓިފައިހުއްޓައި ފެނިވަޑައިގަތްހިނދު، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. މިކަންމިވީ އަހުރެންގެ ވެރިރަސްކަލާނގެ ފަޟްލުވަންތަ ކަމުންނެވެ. (އެއީ) އަހުރެން ނިއުމަތަށް ޝުކުރުކުރަނީތޯ، ނުވަތަ ދެކޮޅުވެރިވަނީތޯ އިމްތިހާނުކުރެއްވުމަށްޓަކައެވެ. ޝުކުރުކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، އޭނާ ޝުކުރުކުރާކަން ކަށަވަރީ، ހަމައޭނާގެ އަމިއްލަ ނަފްސަށެވެ. އަދި (ނިއުމަތަށް) ދެކޮޅުހަދާމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އަހުރެންގެ ވެރިރަސްކަލާނގެއީ، ފުދިވޮޑިގެންވާ، ދީލަތިވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","قال نكروا لها عرشها ننظر أتهتدي أم تكون من الذين لا يهتدون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އެކަމަނާއަށް އެނގިވަޑައިގަނޭތޯ، ނުވަތަ އެނގިވަޑައިނުގަނޭތޯ ބެއްލެވުމަށް، ތިޔަބައިމީހުން އެކަމަނާގެ ތަޚުތުގެ ސިފަ ބަދަލުކޮށްލާށެވެ!","",""],["","","","فلما جاءت قيل أهكذا عرشك قالت كأنه هو وأوتينا العلم من قبلها وكنا مسلمين","ފަހެ، އެކަމަނާ ވަޑައިގަތުމުން ދެންނެވިއެވެ. ކަމަނާގެ ތަޚުތު ވަނީ މިފަދައިންތޯއެވެ. އެކަމަނާ ދެންނެވިއެވެ. އެއާއި މިއާ ހަމަ އެއްފަދައެވެ. (ސުލައިމާނުގެފާނު ވިދާޅުވިއެވެ.) އެކަމަނާގެ ކުރިން ތިމަންމެންނަށްވަނީ، އިލްމު ލިބިފައެވެ. އަދި (އެކަމަނާގެ ކުރިން) ތިމަންމެން މުސްލިމު ންކަމުގައި ވީމުއެވެ.","",""],["","","","وصدها ما كانت تعبد من دون الله إنها كانت من قوم كافرين","އަދި ﷲ ފިޔަވައި އެކަމަނާ އަޅުކަންކުރައްވާ ތަކެތި، އެކަމަނާ (ތެދުމަގުން) އެއްކިބާކުރިއެވެ. ހަމަކަށަވަރުން، އެކަމަނާވީ، ކާފިރު ގައުމެއްގެ މީހުންގެ ތެރެއިންނެވެ.","",""],["","","","قيل لها ادخلي الصرح فلما رأته حسبته لجة وكشفت عن ساقيها قال إنه صرح ممرد من قوارير قالت رب إني ظلمت نفسي وأسلمت مع سليمان لله رب العالمين","އެކަމަނާއަށް ދެންނެވިއެވެ. ގަނޑުވަރަށް ވެދެވަޑައިގަންނަވާށެވެ! ފަހެ، އެކަމަނާއަށް އެތަން ފެނިވަޑައިގަތްހިނދު، އެއީ ފެންގަނޑެކޭ ހީފުޅުކުރައްވައި (ފެންގަނޑަކަށް އެރިވަޑައިގަންނަވާގޮތަށް) ދެ ކަށިމަތިފުޅު ކަޝްފުކުރެއްވިއެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އެއީ ހަމަކަށަވަރުން، އޮމާން ބިއްލޫރިން ހެދިފައިވާ ގަނޑުވަރެކެވެ. (ދެން އެކަމަނާ އިސްލާމް ވުމަށް ސުލައިމާނުގެފާނު ވިދާޅުވިހިނދު) އެކަމަނާ ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، އަޅުގެ އަމިއްލަ ނަފްސަށް އަޅު އަނިޔާވެރިވެއްޖައީމެވެ. އަދި ސުލައިމާނުގެފާނުގެ އަރިހުގައިވެ، އާލަމް ތަކުގެވެރި ﷲއަށް ބޯލަނބައި، ކިޔަމަންވެއްޖައީމެވެ.","",""],["","","","ولقد أرسلنا إلى ثمود أخاهم صالحا أن اعبدوا الله فإذا هم فريقان يختصمون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ޘަމޫދު ބާގައިމީހުންގެ ގާތަށް އެއުރެންގެ އަޚު، ސާލިހުގެފާނު ފޮނުއްވީމެވެ. ތިޔަބައިމީހުން ﷲއަށް އަޅުކަންކުރާށޭ އަންގަވަމުންނެވެ. ފަހެ، އެހާރުން އެއުރެން އަރާރުންވާ ދެބަޔަކަށް ބެހިގެންދިޔައޫއެވެ.","",""],["","","","قال يا قوم لم تستعجلون بالسيئة قبل الحسنة لولا تستغفرون الله لعلكم ترحمون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން ރަނގަޅުގޮތުގެ ކުރިން، ނުބައިގޮތް އަވަސްވުމަށް ތިޔައެދެނީ ކީއްވެގެން ހެއްޔެވެ؟ ތިޔަބައިމީހުންނަށް ރަހުމަތް ލެއްވުމަށްޓަކައި ތިޔަބައިމީހުން ފާފަފުއްސެވުންއެދި، ﷲއަށް ދުއާ ނުކުރާނޫހެއްޔެވެ؟","",""],["","","","قالوا اطيرنا بك وبمن معك قال طائركم عند الله بل أنتم قوم تفتنون","އެއުރެން ދެންނެވޫއެވެ. ކަލޭގެފާނާއި، ކަލޭގެފާނުގެ އަރިހުގައިވާ މީހުންގެ ސުންޕާކަން ތިމަންމެންނަށް ޖެހިއްޖެއެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންނަށް ސުންޕާގޮތް މެދުވެރިވުންވަނީ، ﷲގެ ހަޒުރަތު ގައެވެ. އަދި ކިއެއްތަ! ތިޔަބައިމީހުންނީ، އިމްތިހާނު ވެވޭ ބަޔެކެވެ.","",""],["","","","وكان في المدينة تسعة رهط يفسدون في الأرض ولا يصلحون","އަދި އެރަށުގައި ނުވަމީހަކު އުޅުނެވެ. އެއުރެން ބިމުގައި ފަސާދަ އުފައްދަމުން ގެންދެތެވެ. އަދި އެއުރެން (އެއްވެސް ކަމެއް) އިޞްލާޙެއް ނުކުރެތެވެ.","",""],["","","","قالوا تقاسموا بالله لنبيتنه وأهله ثم لنقولن لوليه ما شهدنا مهلك أهله وإنا لصادقون","އެއުރެން ބުނެފޫއެވެ. ރޭގަނޑުގެ ވަގުތުގައި އެކަލޭގެފާނާއި، އެކަލޭގެފާނުގެ އަހުލުވެރިން އަވަހާރަކޮށްލައި، ނެތިކޮށްލުމަށް ﷲ ގަންދީ ތިޔަބައިމީހުން ހުވާކުރާށެވެ! ދެން ހަމަކަށަވަރުން، އެކަލޭގެފާނުގެ ބަލަދުވެރިޔާ ގާތުގައި ތިމަންމެން ބުނާހުށީމެވެ. (އެކަލޭގެފާނާއި) އެކަލޭގެފާނުގެ އަހުލުވެރިން އަވަހާރަކޮށްލިތަނެއް ތިމަންމެން ނުވެސް ދެކެމުއެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންމެންނަކީ، ތެދުވެރިންކަން ކަށަވަރެވެ.","",""],["","","","ومكروا مكرا ومكرنا مكرا وهم لا يشعرون","އަދި އެއުރެން މަކަރުވެރި ރޭވުމެއް ރޭވިއެވެ. އަދި ތިމަންރަސްކަލާނގެވެސް ރޭވުމެއް ރޭއްވެވީމެވެ. އެއުރެންނަކަށް އެކަމެއް ނޭނގެއެވެ.","",""],["","","","فانظر كيف كان عاقبة مكرهم أنا دمرناهم وقومهم أجمعين","ފަހެ، އެއުރެންގެ މަކަރުވެރި ރޭވުމުގެ ނިމުންވަނީ ކޮންފަދައަކުންކަން ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާށެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެންނާއި އެއުރެންގެ ގައުމުގެ އެންމެން ހަލާކުކޮށް ނެތިކޮށްލެއްވީމެވެ.","",""],["","","","فتلك بيوتهم خاوية بما ظلموا إن في ذلك لآية لقوم يعلمون","ފަހެ، އެހުރީ އެއުރެންގެ އަނިޔާވެރިކަމުގެ ސަބަބުން ވީރާނާވެފައިވާ އެއުރެންގެ ގޯތިގެދޮރެވެ. ހަމަކަށަވަރުން، އެކަންތަކުގައި ދަންނަ ބަޔަކަށް ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","وأنجينا الذين آمنوا وكانوا يتقون","އަދި އީމާންވެ ތަގުވާވެރިކަންމަތީ އުޅުނުމީހުން، ތިމަންރަސްކަލާނގެ ސަލާމަތްކުރެއްވީމެވެ.","",""],["","","","ولوطا إذ قال لقومه أتأتون الفاحشة وأنتم تبصرون","ލޫޠުގެފާނު، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް ވިދާޅުވިހިނދު (ހަނދުމަކުރާށެވެ!) ތިޔަބައިމީހުން ދެކެދެނެތިބި ޙާލު، ފާޙިޝް ޢަމަލުތައް ކުރަނީހެއްޔެވެ؟","",""],["","","","أئنكم لتأتون الرجال شهوة من دون النساء بل أنتم قوم تجهلون","ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ޝަހްވާނީ އެދުން ފުއްދުމަށްޓަކައި އަންހެނުން ފިޔަވައި ފިރިހެނުންނާ ގާތްވަނީ ހެއްޔެވެ؟ އަދި ކިއެއްތަ! ތިޔަބައިމީހުންނަކީ، ތަންދޮރުނޭނގޭ ޖާހިލު ބަޔަކީމުއެވެ.","",""],["","","","فما كان جواب قومه إلا أن قالوا أخرجوا آل لوط من قريتكم إنهم أناس يتطهرون","ފަހެ، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ޖަވާބުކަމުގައި އެއުރެންގެ މިބުނުން ނޫނީ ނުވެއެވެ. ތިޔަބައިމީހުން ލޫޠުގެފާނާއި، އެކަލޭގެފާނަށް ތަބާ ވެގެން ތިބިމީހުން ތިޔަބައިމީހުންގެ ރަށުން ބޭރުކޮށްލާށެވެ! ހަމަކަށަވަރުން، އެއުރެންނީ ތާހިރުވެ ތިބޭބަޔެކެވެ.","",""],["","","","فأنجيناه وأهله إلا امرأته قدرناها من الغابرين","ފަހެ، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނާއި އެކަލޭގެފާނުގެ އަހުލުވެރިން ސަލާމަތްކުރެއްވީމެވެ. އެކަލޭގެފާނުގެ އަނބިކަނބަލުން މެނުވީއެވެ. އަޒާބުގައި ތިބޭމީހުންގެ ތެރެއިން ތިމަންރަސްކަލާނގެ އެކަނބުލޭގެ ހިމެނުއްވީމެވެ.","",""],["","","","وأمطرنا عليهم مطرا فساء مطر المنذرين","އަދި ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް (ހިލައިގެ) ވާރެއެއް ވެއްސެވީމެވެ. ފަހެ، އިންޒާރު ވެވުނު މީހުންގެ (މައްޗަށް ވެހުނު) ވާރޭގެ ނުބައިކަމާއެވެ!","",""],["","","","قل الحمد لله وسلام على عباده الذين اصطفى آلله خير أما يشركون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމްދު ހުރީ ﷲއަށެވެ. އަދި އެކަލާނގެ ޚިޔާރުކުރައްވާފައިވާ، އެކަލާނގެ އަޅުތަކުންގެ މައްޗަށް ސަލާމް ހުށްޓެވެ. ހެޔޮކަންބޮޑީ، ﷲ ހެއްޔެވެ؟ ނުވަތަ އެއުރެން ޝަރީކުކުރާ އެއްޗެތި ހެއްޔެވެ؟","",""],["","","","أمن خلق السماوات والأرض وأنزل لكم من السماء ماء فأنبتنا به حدائق ذات بهجة ما كان لكم أن تنبتوا شجرها أإله مع الله بل هم قوم يعدلون","ނުވަތަ އުޑުތަކާއި، ބިން ހެއްދެވި، އަދި ތިޔަބައިމީހުންނަށްޓަކައި އުޑުން ވާރޭފެން ވެއްސެވި ރަސްކަލާނގެ ހެއްޔެވެ؟ ފަހެ، ރީތިކަމާއި ހިތްފަސޭހަކަމުން ފުރިގެންވާ ބަގީޗާތައް ތިމަންރަސްކަލާނގެ އެ ފެނުން ފެޅުއްވީމެވެ. އެ ބަގީޗާގެ ގަސްތައް ފެޅުވުމަކީ، ތިޔަބައިމީހުންނަށް ކުޅަދާނަވެގެންވާނެ ކަމެއްނޫނެވެ. ﷲއާ އެކުގައި އެހެން އިލާހަކު ވޭހެއްޔެވެ؟ އަދި ކިއެއްތަ! އެއުރެންނީ (ހައްގުން) އެއްކިބާވާ ބަޔެކެވެ.","",""],["","","","أمن جعل الأرض قرارا وجعل خلالها أنهارا وجعل لها رواسي وجعل بين البحرين حاجزا أإله مع الله بل أكثرهم لا يعلمون","ނުވަތަ ގަރާރުވެ ތިބުމުގެ ތަނެއްކަމުގައި، ބިންލައްވައި އެތާނގައި ކޯރުތައް ލައްވައި، އަދި އެތާނގައި ހަރުލައިހުންނަ ފަރުބަދަތައް ލައްވައި، އަދި (މީރުފެނާއި ލޮނުފެނުގެ) ދެ ކަނޑު ދެމެދުގައި ހުރަހެއް ލެއްވި ރަސްކަލާނގެ ހެއްޔެވެ؟ ﷲއާ އެކުގައި އެހެން އިލާހަކު ވޭހެއްޔެވެ؟ އަދި ކިއެއްތަ! އެއުރެންކުރެ ގިނަމީހުނެއް (އެކަމެއް) ނުދަނެތެވެ.","",""],["","","","أمن يجيب المضطر إذا دعاه ويكشف السوء ويجعلكم خلفاء الأرض أإله مع الله قليلا ما تذكرون","ނުވަތަ ދަތި އުނދަގޫ ޙާލު ޖެހިފައިވާ މީހާ، އެކަލާނގެއަށް ދުއާކުރާހިނދު، އެމީހާގެ ދުއާ އިޖާބަކުރައްވައި، އަދި ނުބައިކަން ދުރުކުރައްވައި، އަދި ބިމުގެ ޚަލީފާ އިން ކަމުގައި ތިޔަބައިމީހުންލައްވާ ރަސްކަލާނގެ ހެއްޔެވެ؟ ﷲއާއެކު އެހެން އިލާހަކު ވޭހެއްޔެވެ؟ ތިޔަބައިމީހުން ހަނދުމަކުރަނީ ވަރަށްވެސް މަދުންނެވެ.","",""],["","","","أمن يهديكم في ظلمات البر والبحر ومن يرسل الرياح بشرا بين يدي رحمته أإله مع الله تعالى الله عما يشركون","ނުވަތަ އެއްގަމާއި، ކަނޑުގެ އަނދިރިތަކުގެ ތެރޭގައި، ތިޔަބައިމީހުންނަށް ތެދުމަގު ދައްކަވާ، އަދި އެކަލާނގެ ރަހުމަތް (ގެ ވާރޭ) ގެ ކުރިޔަށް އުފާވެރި ޚަބަރެއްގެ ގޮތުގައި (ވިލާގަނޑުގެ) ވައި ފޮނުއްވާ ރަސްކަލާނގެހެއްޔެވެ؟ ﷲއާއެކު އެހެން އިލާހަކު ވޭހެއްޔެވެ؟ އެއުރެން އެ ޝަރީކުކުރާ ތަކެއްޗަށްވުރެން ﷲ މަތިވެރިވެވޮޑިގެންވެއެވެ.","",""],["","","","أمن يبدأ الخلق ثم يعيده ومن يرزقكم من السماء والأرض أإله مع الله قل هاتوا برهانكم إن كنتم صادقين","ނުވަތަ (ނެތުމުގެތެރޭން) ޚަލްގު ތަކުން އަލަށް އުފައްދަވައި، ދެން އެ ތަކެތި އަލުން އިއާދަކުރައްވައި، އަދި އުޑާއި، ބިމުން ތިޔަބައިމީހުންނަށް ރިޒްގު ދެއްވާ ރަސްކަލާނގެ ހެއްޔެވެ؟ ﷲއާއެކު އެހެން އިލާހަކު ވޭހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ތެދުވެރިން ކަމުގައިވާނަމަ، ތިޔަބައިމީހުންގެ ދަލީލު ތިޔަބައިމީހުން ގެނެސްބަލާށެވެ!","",""],["","","","قل لا يعلم من في السماوات والأرض الغيب إلا الله وما يشعرون أيان يبعثون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲއަށް މެނުވީ، އުޑުތަކާއި، ބިމުގައިވާ އެކަކަށްވެސް ޣައިބު ގައިވާކަމެއް ނޭނގޭނެތެވެ. އަދި އެއުރެން އަލުން ދިރުއްވައި، މަހުޝަރަށް ފޮނުއްވާހުށީ ކޮންއިރަކުންކަން އެއުރެންނަކަށް ނުމެއެނގޭމެއެވެ.","",""],["","","","بل ادارك علمهم في الآخرة بل هم في شك منها بل هم منها عمون","އަދި ކިއެއްތަ! އާޚިރަތާ ހަމަޔަށް އެއުރެންގެ އިލްމު ފޯރީހެއްޔެވެ؟ އަދި ކިއެއްތަ! އެދުވަހާމެދުގައި އެއުރެންވަނީ ޝައްކުކަމެއްގައެވެ. އަދި ކިއެއްތަ؟ އެދުވަހާމެދު އެއުރެންވަނީ ކަނުބަޔަކު ކަމުގައެވެ.","",""],["","","","وقال الذين كفروا أإذا كنا ترابا وآباؤنا أئنا لمخرجون","ކާފިރުވި މީހުން ބުނެފޫއެވެ. ތިމަންމެންނާ، ތިމަންމެންގެ ކާބަފައިން (މަރުވެ) ވެއްޔަށް ވެދާހިނދު، ހަމަކަށަވަރުން، ތިމަންމެންނީ އަލުން (ދިރުއްވައި) ނެރުއްވާނޭ ބަޔެއް ހެއްޔެވެ؟","",""],["","","","لقد وعدنا هذا نحن وآباؤنا من قبل إن هذا إلا أساطير الأولين","ހަމަށަވަރުން، ތިމަންމެންނާއި، ތިމަންމެންގެ ކާބަފައިންނަށް މީގެކުރިންވެސް މިކަންތައް ވައުދުކުރައްވާފައިވެއެވެ. އެވޭލާ މީހުން ދައްކައިއުޅުނު ފުލޯކު ވާހަކަތަކެއް ކަމުގައިމެނުވީ މިކަންތައް ނުވެއެވެ.","",""],["","","","قل سيروا في الأرض فانظروا كيف كان عاقبة المجرمين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ބިމުގައި ދަތުރުފަތުރުކޮށް އުޅޭށެވެ! ފަހެ، ކުށްވެރިންގެ ނަތީޖާ އޮތީ ކިހިނަކުންކަން ތިޔަބައިމީހުން ދެކޭށެވެ!","",""],["","","","ولا تحزن عليهم ولا تكن في ضيق مما يمكرون","އަދި އެއުރެންގެ މައްޗަށް ކަލޭގެފާނު ހިތާމަ ނުކުރައްވާށެވެ! އަދި އެއުރެން މަކަރުހަދާ ކަންތަކުން ހިތްޕުޅު ދަތިވުމެއްގެ ތެރޭގައި ކަލޭގެފާނު ވެވަޑައި ނުގަންނަވާށެވެ!","",""],["","","","ويقولون متى هذا الوعد إن كنتم صادقين","އެއުރެން ބުނެތެވެ. ތިޔަބައިމީހުންނީ، ތެދުބުނާ ބަޔަކު ކަމުގައިވާނަމަ ތިޔަ (ބުނާ އަޒާބުގެ) ވައުދު އަންނާނީ ކޮންއިރަކުން ހެއްޔެވެ؟","",""],["","","","قل عسى أن يكون ردف لكم بعض الذي تستعجلون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އަވަސްކުރުމަށް ތިޔަބައިމީހުން އެދޭ ބައެއްކަންތައް (އެބަހީ: އަޒާބު) ތިޔަބައިމީހުންނާ ދާދިކައިރިވެފައިވުން އެކަށީގެންވެއެވެ.","",""],["","","","وإن ربك لذو فضل على الناس ولكن أكثرهم لا يشكرون","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، މީސްތަކުންގެ މައްޗަށް ފަޟްލުވަންތަ ވެރިރަސްކަލާނގެކަން ކަށަވަރެވެ. އެހެނެއްކަމަކު، އެއުރެންކުރެ ގިނަމީހުން ޝުކުރެއް ނުކުރެތެވެ.","",""],["","","","وإن ربك ليعلم ما تكن صدورهم وما يعلنون","އެއުރެންގެ ހިތްތަކުގައި ފޮރުވާ ކަންތަކާއި، އެއުރެން ފާޅުކުރާ ކަންތައް، ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ދެނެވޮޑިގެންވެއެވެ.","",""],["","","","وما من غائبة في السماء والأرض إلا في كتاب مبين","އަދި އުޑާއި، ބިމުގައިވިޔަސް (އެކަލާނގެއަށް) ފޮރުވިގެންވާ އެއްވެސް ކަމެއް ނުވެއެވެ. އެ ހުރިހާ ކަމެއްވަނީ، ބަޔާންވެގެންވާ ފޮތެއްގައި ލިޔުއްވައިފައެވެ.","",""],["","","","إن هذا القرآن يقص على بني إسرائيل أكثر الذي هم فيه يختلفون","އިސްރާއީލުގެދަރިން، އެކަންކަމާމެދު ދެބަސްވާ ކަންތަކުގެ ތެރެއިން ގިނަކަންތައް ހަމަކަށަވަރުން، މި ގުރްއާން، އެއުރެންނަށް ކިޔައިދީ ބަޔާންކޮށްދެއެވެ.","",""],["","","","وإنه لهدى ورحمة للمؤمنين","އަދި ހަމަކަށަވަރުން، އެ ގުރްއާނަކީ، މުއުމިނު ތަކުންނަށްވާ ހިދާޔަތަކާއި، ރަހުމަތެއްކަން ކަށަވަރެވެ.","",""],["","","","إن ربك يقضي بينهم بحكمه وهو العزيز العليم","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ (ގިޔާމަތް ދުވަހުން) އެއުރެންގެ މެދުގައި އެކަލާނގެ (ޢަދުލުވެރި) ހުކުމްފުޅުން ނިޔާކުރައްވާނެތެވެ. އަދި އެކަލާނގެއީ، ޢަޒީޒުވަންތަ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","فتوكل على الله إنك على الحق المبين","ފަހެ، ކަލޭގެފާނު ﷲއަށް ވަކީލުކުރައްވާށެވެ! ހަމަކަށަވަރުން، ކަލޭގެފާނުވަނީ، ބަޔާންވެގެންވާ ހައްގު މަގުގައެވެ.","",""],["","","","إنك لا تسمع الموتى ولا تسمع الصم الدعاء إذا ولوا مدبرين","ހަމަކަށަވަރުން، މަރުވެފައިތިބޭ މީހުންނަށް ކަލޭގެފާނަކަށް އަޑެއް ނީއްވެވޭނެތެވެ. އަދި ބީރު މީހުންނަށް، އެއުރެން ފުރަގަސްދީ ދާހިނދު، ކަލޭގެފާނު ގޮވައިލައްވާ އަޑެއް ނީއްވެވޭނެތެވެ.","",""],["","","","وما أنت بهادي العمي عن ضلالتهم إن تسمع إلا من يؤمن بآياتنا فهم مسلمون","އަދި ކަނުމީހުންނަށް (އެބަހީ: މަގުފުރެދުމުން ކަނުވެފައިވާ މީހުންނަށް) އެއުރެންގެ މަގުފުރެދުމުން އެއްކިބާކުރައްވައި، (ތެދުމަގު ދައްކަވާ) ހާދީއަކު ކަމުގައި ކަލޭގެފާނު ނުވަމުއެވެ. ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް އީމާންވާ ބަޔަކަށް މެނުވީ ކަލޭގެފާނަކަށް ނީއްވެވޭނެއެވެ. ފަހެ، އެއުރެންނީ، ﷲއަށް ކިޔަމަންވާ މީހުންނެވެ.","",""],["","","","وإذا وقع القول عليهم أخرجنا لهم دابة من الأرض تكلمهم أن الناس كانوا بآياتنا لا يوقنون","އެއުރެންގެ މައްޗަށް (އަޒާބުގެ) ބަސްފުޅު ހައްގު ވާހިނދު، ތިމަންރަސްކަލާނގެ، އެއުރެންނަށްޓަކައި ބިމުން ދާއްބައެއް ނެރުއްވާހުށީމެވެ. އޭތި އެއުރެންނާ ވާހަކަދައްކަމުން ބުނާނެތެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް އީމާން ނުވާ ބަޔަކު ކަމުގައި މީސްތަކުންވިއެވެ.","",""],["","","","ويوم نحشر من كل أمة فوجا ممن يكذب بآياتنا فهم يوزعون","ކޮންމެ އުއްމަތަކުން ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުޅަ މީހުންގެ ތެރެއިން ބަޔަކު ތިމަންރަސްކަލާނގެ އެއްކުރައްވައި، މަހުޝަރަށް ފޮނުއްވާދުވަސް ހަނދުމަކުރާށެވެ! ފަހެ، އެއުރެން ބައިބަޔަށް ބައިތިއްބަވަމުން ގެންދަވާނެތެވެ.","",""],["","","","حتى إذا جاءوا قال أكذبتم بآياتي ولم تحيطوا بها علما أماذا كنتم تعملون","(ﷲގެ ހަޒުރަތަށް) އެއުރެން އަތުވެއްޖައުމަށް ދާނދެނެވެ. އެހިނދު އެކަލާނގެ ވަހީކުރައްވާނެތެވެ. ތިޔަބައިމީހުންނަށް އެއާބެހޭ އިލްމެއް ލިބިފައިނެތް ޙާލު، ތިޔަބައިމީހުން ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުޅައީ ހެއްޔެވެ؟ ނުވަތަ ތިޔަބައިމީހުން ކުރަމުންގެންދިޔައީ ކޮންކަމެއް ހެއްޔެވެ؟","",""],["","","","ووقع القول عليهم بما ظلموا فهم لا ينطقون","އަދި އެއުރެންގެ މައްޗަށް ކަނޑައަޅުއްވާފައިވާ އަޒާބު އައިސް ޖެހިއްޖެއެވެ. އެއީ އެއުރެން އަނިޔާވެރިވީ ކަމަށްޓަކައެވެ. ފަހެ، އެއުރެންނަކަށް (އެދުވަހުން) އެއްވެސް ވާހަކައެއް ނުދެއްކޭނެތެވެ.","",""],["","","","ألم يروا أنا جعلنا الليل ليسكنوا فيه والنهار مبصرا إن في ذلك لآيات لقوم يؤمنون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، ރޭގަނޑު ލައްވާފައިވަނީ، އެވަގުތުގައި އެއުރެން ހަމަހިމޭންކަމާއި، އަރާމު ލިބިތިބުމަށާއި، އަދި ދުވާލު ލައްވާފައިވަނީ (މަސައްކަތްކޮށް އުޅުމަށްޓަކައި) ތަންތަން ފެންނަގޮތުގައިކަން އެއުރެން ނުދެކޭހެއްޔެވެ؟ ހަމަކަށަވަރުން، އީމާންވާ ބަޔަކަށް އެކަންތަކުގައި ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","ويوم ينفخ في الصور ففزع من في السماوات ومن في الأرض إلا من شاء الله وكل أتوه داخرين","ތާޅަފިލި ފުމެލައްވާ ދުވަސް ހަނދުމަކުރާށެވެ! ފަހެ (އެހިނދު) ﷲ އިރާދަކުރެއްވި މީހަކު މެނުވީ، އުޑުތަކާއި، ބިމުގައިވާހާ ބަޔަކު ބިރުން ސިހިގެންދާނެތެވެ. އަދި އެންމެން ދެރަވެ، ނިކަމެތިވެގެންވާ ޙާލުގައި އެކަލާނގެ ހަޒުރަތަށް އަންނާނެތެވެ.","",""],["","","","وترى الجبال تحسبها جامدة وهي تمر مر السحاب صنع الله الذي أتقن كل شيء إنه خبير بما تفعلون","އަދި ފަރުބަދަތައް ތިބާ ދެކެމުއެވެ. އެ ތަކެތި ވިލާތައް ހިނގައިދާގޮތަށް ހިނގައިދާ ޙާލު، ތިބާ ހީކުރަނީ، އެ ތަކެތި ހަރުލައި ހުރިކަމަށެވެ. (އެއީ) ﷲގެ ހެއްދެވުމެވެ. އެކަލާނގެއީ، ހުރިހާ ތަކެއްޗެއް ފުރިހަމަކޮށް ހެއްދެވި ރަސްކަލާނގެއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ތިޔަބައިމީހުންކުރާ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","من جاء بالحسنة فله خير منها وهم من فزع يومئذ آمنون","ހެޔޮކަމާއިގެން އަތުވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް އެއަށްވުރެ ހެޔޮވެގެންވާ ސަވާބު (އާޚިރަތުގައި) ހުށްޓެވެ. އަދި އެދުވަހުން އެއުރެންވަނީ، ހުރިހާ ބިރުވެރިކަމަކުން އަމާން ކަން ލިބިގެންނެވެ.","",""],["","","","ومن جاء بالسيئة فكبت وجوههم في النار هل تجزون إلا ما كنتم تعملون","އަދި ނުބައިކަމާއިގެން އަތުވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންގެ މޫނުތައް ވަތަށް، ނަރަކައަށް ވެއްޓޭހުށްޓެވެ. ތިޔަބައިމީހުން ކޮށްއުޅުނު ކަންތަކަށް މެނުވީ ތިޔަބައިމީހުންނަށް ޖަޒާ ލިބޭނެހެއްޔެވެ؟","",""],["","","","إنما أمرت أن أعبد رب هذه البلدة الذي حرمها وله كل شيء وأمرت أن أكون من المسلمين","ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނަށް އަމުރުކުރައްވާފައިވަނީ، މިރަށުގެ (އެބަހީ: މައްކާގެ) ވެރިރަސްކަލާނގެއަށް އަޅުކަން ކުރުމަށެވެ. އެކަލާނގެއީ، އެރަށް ހުރުމަތް ތެރިކުރެއްވި ރަސްކަލާނގެއެވެ. އަދި ހުރިހާ އެއްޗެއް މިލްކުވެގެންވަނީ އެކަލާނގެއަށެވެ. އަދި ތިމަންކަލޭގެފާނަށް އަމުރުކުރައްވާފައިވަނީ، ތިމަންކަލޭގެފާނު މުސްލިމުންގެ ތެރެއިން ވުމަށެވެ.","",""],["","","","وأن أتلو القرآن فمن اهتدى فإنما يهتدي لنفسه ومن ضل فقل إنما أنا من المنذرين","އަދި ގުރްއާން ކިޔެވުމަށްވެސް ތިމަންކަލޭގެފާނަށް އަމުރުކުރައްވާފައިވެއެވެ. ފަހެ، ތެދުމަގު ލިބިގެންފިމީހާ (ދަންނާށެވެ!) އެމީހާ އެ ތެދުމަގު ލިބިގަންނަކަން ކަށަވަރީ، އޭނާގެ އަމިއްލަ ނަފްސަށްޓަކައެވެ. އަދި މަގުފުރެދިއްޖެމީހާ (ދަންނާށެވެ! އެކަމުގެ ނުބައިކަން އޮތްކަން ކަށަވަރީވެސް ހަމަ އޭނާއަށެވެ!) ފަހެ، ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނު ވާކަން ކަށަވަރީ، އިންޒާރުކުރައްވާ ބޭކަލުންގެ ތެރެއިންނެވެ.","",""],["","","","وقل الحمد لله سيريكم آياته فتعرفونها وما ربك بغافل عما تعملون","އަދި ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމްދު ހުރީ ﷲއަށެވެ. އެކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެކިތައް ތިޔަބައިމީހުންނަށް ނިކަންހުރެ އެކަލާނގެ ދައްކަވާހުށްޓެވެ. ދެން އެކަންތައްތައް ތިޔަބައިމީހުންނަށް އެނގޭނެތެވެ. ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ތިޔަބައިމީހުންކުރާ ޢަމަލު ތަކާމެދު ޣާފިލު ވެވޮޑިގެނެއްނުވެތެވެ.","",""],["","","","بسم الله الرحمن الرحيم طسم","ط س م (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","تلك آيات الكتاب المبين","މިއީ (ކަންތައްތައް) ބަޔާންވެގެންވާ ފޮތުގެ (އެބަހީ: ގުރްއާންގެ) އާޔަތް ތަކެވެ.","",""],["","","","نتلو عليك من نبإ موسى وفرعون بالحق لقوم يؤمنون","އީމާންވާ ބަޔަކަށްޓަކައި މޫސާގެފާނާއި، ފިރްޢައުނުގެ ވާހަކައިން ހައްގު ގޮތުގައި ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ކިޔައިދެއްވަމެވެ.","",""],["","","","إن فرعون علا في الأرض وجعل أهلها شيعا يستضعف طائفة منهم يذبح أبناءهم ويستحيي نساءهم إنه كان من المفسدين","ހަމަކަށަވަރުން، ފިރްޢައުނު، ބިމުގައި ބޮޑާވެގެންފިއެވެ. އަދި އެ ބިމުގެ އަހުލުވެރިން ބައިތަކަކަށް ބަހައިލިއެވެ. އޭގެތެރެއިން އެއްބަޔަކު ނިކަމެތިކުރަމުން ގެންދިޔައެވެ. އެއުރެންގެ ފިރިހެން ދަރިން ގަތުލު ކޮށް، އެއުރެންގެ އަންހެންދަރިން ދޫކޮށްލިއެވެ. ހަމަކަށަވަރުން، އޭނާއަކީ، ފަސާދަކުރާ މީހުންގެ ތެރެއިންވީ މީހެކެވެ.","",""],["","","","ونريد أن نمن على الذين استضعفوا في الأرض ونجعلهم أئمة ونجعلهم الوارثين","އަދި ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވަނީ، ބިމުގައި ދެރަވެ ނިކަމެތިވީ މީހުންނަށް ނިއުމަތް ދެއްވުމަށެވެ. އަދި އެއުރެންނީ (އެހެންމީހުންނަށް މަގުދައްކާ) އިމާމުން ކަމުގައި ލެއްވުމަށެވެ. އަދި (ފިރްޢައުނުގެ ވެރިކަން) ވާރުތަވަނިވި މީހުން ކަމުގައި އެއުރެން ލެއްވުމަށެވެ.","",""],["","","","ونمكن لهم في الأرض ونري فرعون وهامان وجنودهما منهم ما كانوا يحذرون","އަދި ބިމުގައި ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ވެރިކަން ދެއްވުމަށެވެ. އަދި ފިރްޢައުނާއި، ހާމާނާއި، އެ ދެމީހުންގެ ލަޝްކަރަށް، އެއުރެން ބިރުގަންނަ ކަންތައްތައް، އެ ނިކަމެތި މީހުންގެ ފަރާތުން ދެއްކެވުމަށްޓަކައެވެ.","",""],["","","","وأوحينا إلى أم موسى أن أرضعيه فإذا خفت عليه فألقيه في اليم ولا تخافي ولا تحزني إنا رادوه إليك وجاعلوه من المرسلين","އަދި ތިމަންރަސްކަލާނގެ މޫސާގެފާނުގެ މަންމައަށް އިލްހާމްކުރެއްވީމެވެ. ކަމަނާ އެކަލޭގެފާނަށް ކިރުފޮދު އަރުވާހުށިކަމެވެ! ފަހެ، ކަމަނާ އެކަލޭގެފާނުގެ މައްޗަށް ބިރުފުޅުގެންފިނަމަ، އެކަލޭގެފާނު (ފޮށްޓަކަށް ލައްވައިފައި) ކޯރުގެ ތެރެއަށް އެއްލަވާހުށިކަމެވެ! އަދި ކަމަނާ ބިރުފުޅު ނުގަންނާށެވެ! އަދި ހިތާމަވެސް ނުކުރައްވާށެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނު ކަމަނާއަށް ރައްދުކުރައްވާހުށީމެވެ. އަދި އެކަލޭގެފާނު ރަސޫލުންގެ ތެރެއިން ލައްވާހުށީމެވެ.","",""],["","","","فالتقطه آل فرعون ليكون لهم عدوا وحزنا إن فرعون وهامان وجنودهما كانوا خاطئين","ފަހެ، ފިރްޢައުނުގެ އަހުލުވެރިން، އެކަލޭގެފާނު (އޮޔާދަނިކޮށް) ހޮވައި ނެގިއެވެ. އެއީ އެކަލޭގޭފާނު އެއުރެންނަށްހުރި އަދުއްވަކަށް، އަދި ހިތާމައަކަށް ވުމަށްޓަކައެވެ. ހަމަކަށަވަރުން، ފިރްޢައުނާއި، ހާމާނާއި، އެ ދެމީހުންގެ ލަޝްކަރު ވީ ކުށްވެރިން ކަމުގައެވެ.","",""],["","","","وقالت امرأت فرعون قرت عين لي ولك لا تقتلوه عسى أن ينفعنا أو نتخذه ولدا وهم لا يشعرون","އަދި ފިރްޢައުނުގެ އަނބިކަމަނާ ވިދާޅުވިއެވެ. (އޭނާއަކީ) ތިމަންނާއަށާއި، ކަލެޔަށްވާ ލޮލުގެ ފިނިކަމެކެވެ. ތިޔަބައިމީހުން އޭނާ ގަތުލު ނުކުރާށެވެ! އޭނާ ތިމަންމެންނަށް މަންފާކޮށްދީފާނެކަން ނޭނގެއެވެ. ނުވަތަ ތިމަންމެން އޭނާއަކީ ދަރިއަކު ކަމުގައި ހަދާނީއެވެ. އަދި އެއުރެންނަކަށް (އޭގެ ނަތީޖާއެއް) ނޭނގެތެވެ.","",""],["","","","وأصبح فؤاد أم موسى فارغا إن كادت لتبدي به لولا أن ربطنا على قلبها لتكون من المؤمنين","އަދި މޫސާގެފާނުގެ މައިކަމަނާގެ ހިތްޕުޅު (މޫސާގެފާނު ފިޔަވައި އެހެން ހުރިހާ ކަމަކުން) ހުސްވެގެންވެއެވެ. ތިމަންރަސްކަލާނގެ އެކަމަނާގެ ހިތްޕުޅަށް ގަދަކަން ނުދެއްވިނަމަ، އެ ދަރިކަލުންގެ ކަންތައް އެކަމަނާ ފާޅުކުރައްވައިފީހެވެ. (އެއީ ހަރުދަނާ) މުއުމިނުންގެ ތެރެއިން އެކަމަނާ ވެވަޑައިގަތުމަށްޓަކައެވެ.","",""],["","","","وقالت لأخته قصيه فبصرت به عن جنب وهم لا يشعرون","އަދި އެކަމަނާ މޫސާގެފާނުގެ އުޚްތަށް ވިދާޅުވިއެވެ. އޭނާ (އޮޔާދާތަން ބަލަމުން) ފަހަތުންގޮސް ބަލާށެވެ! ފަހެ، އޭނާ ދުރުގައި ހުރެގެން އެހެންމީހުންނަށް ނޭނގޭގޮތުން އެކަލޭގެފާނަށް ބަލަމުންދިޔައެވެ.","",""],["","","","وحرمنا عليه المراضع من قبل فقالت هل أدلكم على أهل بيت يكفلونه لكم وهم له ناصحون","އަދި އޭގެކުރިން ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް (އެކަލޭގެފާނުގެ މައިކަމަނާ މެނުވީ) އެހެން ކިރުމައިން ހަރާމްކުރެއްވީމެވެ. ދެން އެކަލޭގެފާނުގެ އުޚްތު ބުންޏެވެ. ތިޔަބައިމީހުންނަށްޓަކައި، އޭނާ ބަލަހައްޓައިދޭނެ ގެއެއްގެ އަހުލުވެރިން ތިޔަބައިމީހުންނަށް ތިމަން ދައްކަންހެއްޔެވެ؟ އަދި އެއުރެން އޭނާ ރަނގަޅަށް ބަލަހައްޓާނެތެވެ.","",""],["","","","فرددناه إلى أمه كي تقر عينها ولا تحزن ولتعلم أن وعد الله حق ولكن أكثرهم لا يعلمون","ފަހެ، ތިމަންރަސްކަލާނގެ، އެކަލޭގެފާނުގެ މައިކަމަނާއަށް އެކަލޭގެފާނު ރައްދުކުރެއްވީމެވެ. އެއީ އެކަމަނާގެ ލޯފުޅަށް ފިނިކަން ޙާޞިލު ވުމަށްޓަކައެވެ. އަދި އެކަމަނާ ހިތާމަ ނުކުރެއްވުމަށްޓަކައެވެ. އަދި ހަމަކަށަވަރުން، ﷲގެ ވައުދު ފުޅަކީ، ހައްގު ތެދުކަން އެކަމަނާ ދެނެގަތުމަށްޓަކައެވެ. އެހެނެއްކަމަކު، އެއުރެންކުރެ ގިނަމީހުންނަކަށް އެކަމެއް ނޭނގެތެވެ.","",""],["","","","ولما بلغ أشده واستوى آتيناه حكما وعلما وكذلك نجزي المحسنين","އަދި އެކަލޭގެފާނު ބޮޑުފުޅުވެ، ފުރާފުރިހަމަވިހިނދު ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ހިކުމަތާއި، އިލްމު ދެއްވީމެވެ. އިހްސާން ތެރިންނަށް ތިމަންރަސްކަލާނގެ ޖަޒާދެއްވަނީ އެފަދައިންނެވެ.","",""],["","","","ودخل المدينة على حين غفلة من أهلها فوجد فيها رجلين يقتتلان هذا من شيعته وهذا من عدوه فاستغاثه الذي من شيعته على الذي من عدوه فوكزه موسى فقضى عليه قال هذا من عمل الشيطان إنه عدو مضل مبين","އަދި އެރަށުގެ އަހުލުވެރިން، ޣާފިލުކަމުގައިތިބި ތަންވަޅެއްގައި އެކަލޭގެފާނު ރަށުތެރެއަށް ވެދެވަޑައިގަތެވެ. ދެން އެކަލޭގެފާނަށް ފެނިވަޑައިގަތީ، ތަޅާފޮޅާ ދެމީހެކެވެ. އެތަނުން އެކަކީ، އެކަލޭގެފާނުގެ ބައިގެ މީހެކެވެ. އަނެކަކީ އެކަލޭގެފާނުގެ އަދުއްވުންގެ ތެރެއިންވާ މީހެކެވެ. ފަހެ، އެކަލޭގެފާނުގެ އަދުއްވުންގެ ތެރެއިންވާ މީހާއާ ދެކޮޅަށް އެކަލޭގެފާނުގެ ބައިގެ މީހާއަށް ވާގިދެއްވުންއެދި އެކަލޭގެފާނަށް އޭނާ ގޮވައިލިއެވެ. އެހިނދު މޫސާގެފާނު އޭނާގެ ގައިގައި މުށްކަވާފައި ޖެއްސެވިއެވެ. ފަހެ (އެހިނދު) އޭނާގެ ކަންތައް ނިންމަވައިލެއްވިއެވެ. (އެބަހީ: އޭނާގެ ގައިގައި ޖެއްސެވުމުން، އޭނާ މަރުވީއެވެ.) އެކަލޭގެފާނު ވިދާޅުވިއެވެ. މިކަންތައްމިވީ ޝައިތާނާގެ ޢަމަލުގެ ތެރެއިންނެވެ. ހަމަކަށަވަރުން، އެ ޝައިތާނާއީ، ބަޔާންވެގެންހުރި މަގުފުރައްދާ އަދާވަތް ތެރިޔެކެވެ.","",""],["","","","قال رب إني ظلمت نفسي فاغفر لي فغفر له إنه هو الغفور الرحيم","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، އަޅުގެ ނަފްސަށް އަޅު އަނިޔާކޮށްފީމެވެ. ފަހެ، މިއަޅާޔަށް އިބަރަސްކަލާނގެ ފާފަފުއްސަވާނދޭވެ! ދެން އެކަލާނގެ، އެކަލޭގެފާނަށް ފާފަފުއްސެވިއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","قال رب بما أنعمت علي فلن أكون ظهيرا للمجرمين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! އިބަރަސްކަލާނގެ މިއަޅާޔަށް ނިއުމަތް ދެއްވާފައިވާތީ، ފަހެ، ދުވަހަކުވެސް ކުށްވެރިންނަށް ވާގިވެރިވާ މީހެއްކަމުގައި މިއަޅާ ނުވާހުށީމެވެ.","",""],["","","","فأصبح في المدينة خائفا يترقب فإذا الذي استنصره بالأمس يستصرخه قال له موسى إنك لغوي مبين","ފަހެ، އެކަލޭގެފާނު އެރަށުގައި ބިރުވެރި ޙާލުގައި (އަތުވެދާނެ ނުރައްކަލަކަށް) އިންތިޒާރު ކޮށްކޮށް ހުންނެވިއެވެ. ފަހެ، އެހާރުން އެކަލޭގެފާނުގެ އަރިހުން ކުރީދުވަހު އެހީއަށް އެދުނުމީހާ (އަނެއްކާވެސް) އެކަލޭގެފާނުގެ ކިބައިން އެހީއަށްއެދި ގޮވައިލިއެވެ. މޫސާގެފާނު އޭނާއަށް ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ކަލެޔަކީ، ފާޅުވެގެންހުރި ފުރެދުންތެރިއެއްކަން ކަށަވަރެވެ.","",""],["","","","فلما أن أراد أن يبطش بالذي هو عدو لهما قال يا موسى أتريد أن تقتلني كما قتلت نفسا بالأمس إن تريد إلا أن تكون جبارا في الأرض وما تريد أن تكون من المصلحين","ފަހެ، އެ ދެމީހުންގެ އަދާވަތް ތެރިޔަކު ކަމުގައިވާ މީހާގެ މައްޗަށް ގަދަކަން ދެއްކެވުމަށް އެކަލޭގެފާނު ހީފުޅުކުރެއްވިހިނދު، އެމީހާ ބުންޏެވެ. އޭ މޫސާގެފާނެވެ! ކަލޭގެފާނު އިއްޔެ މީހަކު މެރުއްވިފަދައިން، ތިމަންވެސް މެރުއްވުމަށް ގަސްދުކުރައްވަނީތޯއެވެ؟ ބިމުގައި ޖައްބާރަކަށްވެގެން އުޅުއްވުން މެނުވީ ކަލޭގެފާނު އެދިވަޑައެއް ނުގަންނަވަމުއެވެ. އަދި އިސްލާހުކުރާ މީހުންގެ ތެރެއިން ވުމަކަށްވެސް ކަލޭގެފާނު އެދިވަޑައެއް ނުގަންނަވަމުއެވެ.","",""],["","","","وجاء رجل من أقصى المدينة يسعى قال يا موسى إن الملأ يأتمرون بك ليقتلوك فاخرج إني لك من الناصحين","އަދި އެރަށުގެ އެންމެދުރު ފަރާތުން މީހަކު ދުވަމުންއައިސް ދެންނެވިއެވެ. އޭ މޫސާގެފާނެވެ. ހަމަކަށަވަރުން، ރަށުގެ ބޮޑުން ކަލޭގެފާނު ގަތުލުކުރުމަށް އެބަ ސައްލާކުރެތެވެ. ފަހެ، ކަލޭގެފާނު (މިރަށުން) ނުކުމެވަޑައިގަންނަވާށެވެ! ހަމަކަށަވަރުން، ތިމަންވަނީ ކަލޭގެފާނަށް ނަސޭހަތް ތެރިވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["","","","فخرج منها خائفا يترقب قال رب نجني من القوم الظالمين","ފަހެ، އެކަލޭގެފާނު ބިރުވެރި ޙާލުގައި (އަތުވެދާނެ ނުރައްކަލަކަށް) އިންތިޒާރުކުރައްވަމުން އެރަށުން ނުކުމެވަޑައިގެންނެވިއެވެ. އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! އަނިޔާވެރިވި މީހުންގެ ކިބައިން މިއަޅާ ސަލާމަތްކުރައްވާނދޭވެ!","",""],["","","","ولما توجه تلقاء مدين قال عسى ربي أن يهديني سواء السبيل","އަދި އެކަލޭގެފާނު މަދްޔަނާ ދިމާއަށް ވަޑައިގެންނެވިހިނދު ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާނގެ މިއަޅާއަށް ސީދާވެގެންވާ ތެދުމަގަށް މަގު ދައްކަވާށިއެވެ!","",""],["","","","ولما ورد ماء مدين وجد عليه أمة من الناس يسقون ووجد من دونهم امرأتين تذودان قال ما خطبكما قالتا لا نسقي حتى يصدر الرعاء وأبونا شيخ كبير","އަދި އެކަލޭގެފާނު މަދްޔަންގެ ފެންވަޅުގެ ކައިރިޔަށް ވަޑައިގެންނެވިހިނދު، މީސްތަކުންގެ ތެރެއިން ގިނަބަޔަކު (އެއުރެންގެ ޖަނަވާރުތަކަށް) ފެންދެނިކޮށް އެކަލޭގެފާނު ދެކެވަޑައިގެންނެވިއެވެ. އަދި އެއުރެންނާ ތަންކޮޅެއް ދުރުގައި ދެއަންހެނަކު ތިބެގެން (އެއުރެންގެ ޖަނަވާރުތައް) ދުރަށް ޖައްސާތީ ދެކެވަޑައިގެންނެވިއެވެ. (އެހިނދު) އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަ ދެމީހުން ތިޔަހެން ހަދަނީ ކީއްވެގެން ހެއްޔެވެ؟ އެ ދެ އަންހެނުން ދެންނެވިއެވެ. ޖަނަވާރުތައް ހުއިހައްޕާމީހުން (އެއުރެންގެ ޖަނަވާރުތަކަށް ފެންދީ) ދުރަށް ހިނގައްޖައުމަށް ދާނދެން، ތިމަންމެންގެ ޖަނަވާރަށް ތިމަންމެންނަކަށް ފެނެއް ނުދެވޭނެތެވެ. އަދި އަހުރެމެންގެ ބައްޕައަކީ (އެފަދަކަމެއް ކުރެއްވޭވަރަށްވުރެ) އުމުރުން ދުވަސްވެފައިވާ މުސްކުޅިއެކެވެ.","",""],["","","","فسقى لهما ثم تولى إلى الظل فقال رب إني لما أنزلت إلي من خير فقير","ފަހެ، އެކަލޭގެފާނު (އެ ދެ އަންހެނުންގެ ޖަނަވާރުތަކަށްޓަކައި) އެ ދެ އަންހެނުންނަށް ފެންދެއްވިއެވެ. ދެން އެކަލޭގެފާނު އެނބުރި (ގަހެއްގެ) ހިޔަލަށް ވަޑައިގަތެވެ. ފަހެ، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! އިބަރަސްކަލާނގެ މިއަޅާއަށް ދެއްވި ކޮންމެ ހެވަކަށް ހަމަކަށަވަރުން، މިއަޅާވަނީ ބޭނުންވެގެންނެވެ.","",""],["","","","فجاءته إحداهما تمشي على استحياء قالت إن أبي يدعوك ليجزيك أجر ما سقيت لنا فلما جاءه وقص عليه القصص قال لا تخف نجوت من القوم الظالمين","ފަހެ، އެ ދެ އަންހެނުންކުރެ އެކަކު ލަދުރަކިގޮތެއްގައި ހިނގާފައި އެކަލޭގެފާނުގެ އަރިހަށްއައިސް ދެންނެވިއެވެ. ހަމަކަށަވަރުން، ތިމަންގެ ބައްޕާ ކަލޭގެފާނަށް އެބަގޮވައިލައްވައެވެ. (އެއީ) ކަލޭގެފާނު ތިމަންމެންނަށް ފެން ދެއްވިކަމުގެ މައްޗަށް އުޖޫރައެއް ދެއްވުމަށްޓަކައެވެ. ފަހެ، އެކަލޭގެފާނު އެކަލޭގެފާނުގެ އަރިހަށް (އެބަހީ: އެ ދެ އަންހެންކުދިންގެ ބައްޕާގެ އަރިހަށް) ވަޑައިގެން އެކަލޭގެފާނުގެ ވާހަކަ ކިޔައިދެއްވި ހިނދު، އެކަލޭގެފާނު (އެބަހީ: އެ ދެ އަންހެންކުދިންގެ ބައްޕާ) ވިދާޅުވިއެވެ. ކަލޭގެފާނު ބިރުފުޅު ނުގަންނާށެވެ! އަނިޔާވެރިވީ މީހުންގެ ކިބައިން ކަލޭގެފާނު ސަލާމަތް ވެވަޑައިގެންފީމުއެވެ.","",""],["","","","قالت إحداهما يا أبت استأجره إن خير من استأجرت القوي الأمين","އެ ދެ އަންހެނުންކުރެ އެކަކު ދެންނެވިއެވެ. އޭ ބައްޕާއެވެ! އޭނާއަށް ނޯކިރީއެއް ދެއްވާފައި ބަހައްޓަވާށެވެ! ހަމަކަށަވަރުން، ކަލޭގެފާނު ނޯކަރެއް ކަމުގައި ބަހައްޓަވަން އެންމެރަނގަޅު މީހަކީ، ގައިބާރުހުރި އަމާނާތްތެރިޔެކެވެ.","",""],["","","","قال إني أريد أن أنكحك إحدى ابنتي هاتين على أن تأجرني ثماني حجج فإن أتممت عشرا فمن عندك وما أريد أن أشق عليك ستجدني إن شاء الله من الصالحين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިމަން ގަސްދުކުރަނީ ތިމަންގެ މިތިބަ ދެ އަންހެން ދަރިންކުރެ އެކަކު، ކަލޭގެފާނާ ދެވުމަށެވެ. އަށްއަހަރު ވަންދެން ތިމަންނާއަށް ޚިދުމަތް ކޮށްދެއްވުމުގެ ޝަރުޠުގެ މަތިންނެވެ. ފަހެ، ދިހައަހަރު ކަލޭގެފާނު ހަމަކުރައްވައިފިނަމަ، އެއީ ކަލޭގެފާނުގެ ހެޔޮފުޅުކަމެވެ. އަދި ކަލޭގެފާނަށް އުނދަގޫކުރާކަށް ތިމަން ނޭދެމެވެ. ﷲ އިރާދަކުރެއްވިއްޔާ ތިމަންނާއީ ސާލިހުންގެ ތެރެއިންވާ މީހެއްކަން ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނޫއެވެ.","",""],["","","","قال ذلك بيني وبينك أيما الأجلين قضيت فلا عدوان علي والله على ما نقول وكيل","އެކަލޭގެފާނު (އެބަހީ: މޫސާގެފާނު) ވިދާޅުވިއެވެ. އެއީ ތިމަންނާއާ ކަލޭގެފާނާ ދެމެދު އެއްބަސްވީގޮތެވެ. ދެ މުއްދަތުންކުރެ ކޮންމެ މުއްދަތެއް ތިމަން ވޭތިކުރިޔަސް، ފަހެ، ތިމަންގެ މައްޗަކަށް ދެކޮޅުވެރިވުމެއްނެތެވެ. އަދި ތިމަންމެން މި ބުނާބަހުގެ މައްޗަށް ﷲ ހެކިވެވޮޑިގެންވެއެވެ.","",""],["","","","فلما قضى موسى الأجل وسار بأهله آنس من جانب الطور نارا قال لأهله امكثوا إني آنست نارا لعلي آتيكم منها بخبر أو جذوة من النار لعلكم تصطلون","ފަހެ، މޫސާގެފާނު އެ މުއްދަތު ހަމަކުރައްވައި، އެކަލޭގެފާނުގެ އަހުލުވެރިންނާއެކު (ދަތުރުކުރައްވައި) ވަޑައިގެންނެވިހިނދު، ޠޫރު ފަރުބަދައިގެ ކައިރިން އަލިފާންގަނޑެއް ފެނިވަޑައިގަތެވެ. އެކަލޭގެފާނު، އެކަލޭގެފާނުގެ އަހުލުވެރިންނަށް ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން މިތާ ތިބޭށެވެ! ހަމަކަށަވަރުން، ތިމަންނާއަށް އަލިފާންގަނޑެއް ފެނިއްޖެއެވެ. ތިޔަބައިމީހުންގެ ގާތަށް އެތަނުން ޚަބަރެއް ނުވަތަ ތިޔަބައިމީހުން ހީފިލުވުމަށް އަލިފާންކޮޅެއް ގެނެސްދެވޭތޯ ބަލާހުށީމެވެ.","",""],["","","","فلما أتاها نودي من شاطئ الواد الأيمن في البقعة المباركة من الشجرة أن يا موسى إني أنا الله رب العالمين","ފަހެ، އެކަލޭގެފާނު އެ އަލިފާންގަނޑުގެ ކައިރިޔަށް ވަޑައިގަތްހިނދު، ވާދީގެ ކަނާތްފަރާތުގައިވާ ބަރަކާތް ތެރި ތަނަކުން ގަހެއްގެ ތެރެއިން އެކަލޭގެފާނަށް ނިދާއިއްވެވިއެވެ. އޭ މޫސާގެފާނެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެއީ، އާލަމްތަކުގެ ވެރި ﷲއެވެ.","",""],["","","","وأن ألق عصاك فلما رآها تهتز كأنها جان ولى مدبرا ولم يعقب يا موسى أقبل ولا تخف إنك من الآمنين","އަދި ކަލޭގެފާނުގެ އަސާކޮޅު އެއްލަވާށެވެ! ފަހެ، އެ އަސާކޮޅު (އެއްލެވީމާ) ހަރުފައެއް ފަދައިން ހެލިފެލިވާތީ އެކަލޭގެފާނު ދެކެވަޑައިގަތްހިނދު (ބިރުފުޅުން) ފުރަގަސްދެއްވައި ދުވެވަޑައިގަތެވެ. އަދި އެނބުރި ވަޑައެއްނުގަތެވެ. (ވަހީ އިއްވެވިއެވެ.) އޭ މޫސާގެފާނެވެ! ކުރިމަތިލައްވައި ވަޑައިގަންނަވާށެވެ! އަދި ބިރުފުޅު ނުގަންނާށެވެ! ހަމަކަށަވަރުން، ކަލޭގެފާނުވަނީ އަމާންކަން ލިބިގެންވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["","","","اسلك يدك في جيبك تخرج بيضاء من غير سوء واضمم إليك جناحك من الرهب فذانك برهانان من ربك إلى فرعون وملئه إنهم كانوا قوما فاسقين","އަދި ކަލޭގެފާނު ހެދުންކޮޅުގެ މަންސަފާއަށް އަތްޕުޅު ލައްވާށެވެ! އެއްވެސް ބަލިމަޑުކަމެއްގެ ނުބަޔަކާނުލައި، ހުދުކޮށް (ވިދަވިދާ އޮންނަ ގޮތުގައި) އެ އަތްޕުޅު ނުކުންނާނެތެވެ. އަދި ކަލޭގެފާނުގެ އަތްޕުޅު، ބިރުވެރިކަމުން ކަލޭގެފާނުގެ އަރިކަށިފުޅަށް ލަފައިލައްވާށެވެ! ފަހެ، އެ ދެކަންތަކަކީ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ފިރްޢައުނާއި، އޭނާގެ ބޮޑުންނަށް (ދެއްކެވުމަށް) ވާ ދެ ހުއްޖަތެވެ. ހަމަކަށަވަރުން، ފާސިގު ބަޔަކު ކަމުގައި އެއުރެންވޫއެވެ.","",""],["","","","قال رب إني قتلت منهم نفسا فأخاف أن يقتلون","އެކަލޭގެފާނު ދެންނެވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، މިއަޅާވަނީ، އެއުރެންގެ ތެރެއިން މީހަކު ގަތުލު ކޮށްފައެވެ. ފަހެ، އެއުރެން މިއަޅާ ގަތުލު ކޮށްފާނެތީ، މިއަޅާ ބިރުގަނެތެވެ.","",""],["","","","وأخي هارون هو أفصح مني لسانا فأرسله معي ردءا يصدقني إني أخاف أن يكذبون","އަދި މިއަޅާގެ އަޚު، ހާރޫނު މިއަޅާއަށްވުރެ ދޫފަސޭހަކަން ބޮޑެވެ. ފަހެ، އަޅުގެ ބަސްތެދުކޮށް އަޅާއަށް އެހީތެރިވުމަށް މިއަޅާއަށް އެކުގައި އެކަލޭގެފާނު ރަސޫލުކަމާއިގެން ފޮނުއްވައިފާނދޭވެ! ހަމަކަށަވަރުން، އެއުރެން މިއަޅާ ދޮގުކޮށްފާނެކަމަށް މިއަޅާ ބިރުގަނެތެވެ.","",""],["","","","قال سنشد عضدك بأخيك ونجعل لكما سلطانا فلا يصلون إليكما بآياتنا أنتما ومن اتبعكما الغالبون","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ކަލޭގެފާނުގެ އަޚު ފޮނުއްވުމުން ކަލޭގެފާނުގެ މުލައްދަނޑިފުޅަށް ތިމަންރަސްކަލާނގެ ގަދަކަން ދެއްވާހުށީމެވެ. އަދި ތިޔަ ދެކަލުންނަށް ބާރެއް ދެއްވާހުށީމެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ ދެއްވި މުއުޖުޒާތްގެ ސަބަބުން، އެއުރެންނަކަށް ތިޔަ ދެކަލުންނާ ހަމައަށް (އުނދަގުލެއް ދޭކަށް) ނާދެވޭހުށްޓެވެ. ތިޔަ ދެކަލުންނާއި، ތިޔަ ދެކަލުންނަށް ތަބާ ވީ މީހުންނަކީ (ނަސްރު ލިބި) ގަދަވާނޭ މީހުންނެވެ.","",""],["","","","فلما جاءهم موسى بآياتنا بينات قالوا ما هذا إلا سحر مفترى وما سمعنا بهذا في آبائنا الأولين","ފަހެ، ބަޔާންވެގެންވާ ޙާލު، ތިމަންރަސްކަލާނގެ ހެކިތަކާއިގެން މޫސާގެފާނު އެއުރެންގެ ގާތަށް ވަޑައިގަތްހިނދު، އެއުރެން ބުނޫއެވެ. މިއީ އަމިއްލައަށް ހަދައިގެންއުޅޭ ޖާދޫއެއްކަމުގައި ނޫނީ ނުވެތެވެ. އަދި ތިމަންމެންގެ ކުރީގައި އުޅުނު ކާބަފައިންގެ ތެރޭގައިވެސް މިފަދަ ވާހަކައެއް (ވާކަމަކަށް) ތިމަންމެން ނާހަމުއެވެ.","",""],["","","","وقال موسى ربي أعلم بمن جاء بالهدى من عنده ومن تكون له عاقبة الدار إنه لا يفلح الظالمون","އަދި މޫސާގެފާނު ވިދާޅުވިއެވެ. އެކަލާނގެ ހަޒުރަތުން ތެދުމަގާއިގެން އައީ ކާކުކަން، އަދި އާޚިރަތް ދުވަހުން ތައުރީފު ލިބިގެންވާ ނިމުމެއް ލިބޭނީ ކާކަށްކަން، އެންމެމޮޅަށް ދެނެވޮޑިގެންވަނީ ތިމަންމެންގެ ވެރިރަސްކަލާނގެއެވެ. ހަމަކަށަވަރުން، އަނިޔާވެރިންނެއް ނުދިނޭނެތެވެ.","",""],["","","","وقال فرعون يا أيها الملأ ما علمت لكم من إله غيري فأوقد لي يا هامان على الطين فاجعل لي صرحا لعلي أطلع إلى إله موسى وإني لأظنه من الكاذبين","ފިރްޢައުނު ބުންޏެވެ. އޭ (އަހުރެންގެ ގައުމުގެ) ބޮޑުންނޭވެ! އަހުރެން ފިޔަވައި އެހެން އިލާހަކު ތިޔަބައިމީހުންނަށް ވާކަމެއް އަހުރެންނަށް އެނގިފައެއް ނުވެތެވެ. އޭ ހާމާނެވެ! އަހުރެންނަށް މަށިން އީޓު ހަދައިދޭށެވެ! އަދި އަހުރެންނަށް އުސްގަނޑުވަރެއް ތައްޔާރުކޮށްދޭށެވެ! (އެއީ) މޫސާގެފާނުންގެ އިލާހު އަހުރެންނަށް ފެނޭތޯއެވެ. އަދި ހަމަކަށަވަރުން، އަހުރެންނަށް ހީވަނީ، އެކަލޭގެފާނުވަނީ ދޮގުވެރިންގެ ތެރެއިން ކަމަށެވެ.","",""],["","","","واستكبر هو وجنوده في الأرض بغير الحق وظنوا أنهم إلينا لا يرجعون","އަދި އޭނާއާއި، އޭނާގެ ލަޝްކަރު ހައްގަކާ ނުލައި ބިމުގައި ބޮޑާވެގަތެވެ. އަދި ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް އެއުރެން އަނބުރާ ރުޖޫއަ ނުކުރައްވާނެކަމަށް އެއުރެން ހީކުރޫއެވެ.","",""],["","","","فأخذناه وجنوده فنبذناهم في اليم فانظر كيف كان عاقبة الظالمين","ފަހެ، ތިމަންރަސްކަލާނގެ އޭނާއާއި، އޭނާގެ ލަޝްކަރު ހިއްޕަވައި، ދެން ތިމަންރަސްކަލާނގެ އެއުރެން ކަނޑު ލެއްވީމެވެ. ފަހެ، އަނިޔާވެރިންގެ ނިމުންވަނީ ކޮންފަދައަކުންކަން ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާށެވެ!","",""],["","","","وجعلناهم أئمة يدعون إلى النار ويوم القيامة لا ينصرون","އަދި ނަރަކަޔަށް (ވަނުމަށް މީސްތަކުންނަށް) ގޮވާ ޒަޢީމުން ކަމުގައި ތިމަންރަސްކަލާނގެ އެއުރެން ލެއްވީމެވެ. އަދި ގިޔާމަތް ދުވަހުން އެއުރެންނަކަށް ނަސްރެއް ނުލިބޭނެތެވެ.","",""],["","","","وأتبعناهم في هذه الدنيا لعنة ويوم القيامة هم من المقبوحين","އަދި ތިމަންރަސްކަލާނގެ މިދުނިޔެމަތީގައިވެސް، އެއުރެންނަށް ލައުނަތް ލެއްވީމެވެ. އަދި ގިޔާމަތް ދުވަހުގައި، އެއުރެންނީ (ﷲގެ ރަހުމަތުން) ދުރުކުރައްވާފައިވާ ބަޔެކެވެ.","",""],["","","","ولقد آتينا موسى الكتاب من بعد ما أهلكنا القرون الأولى بصائر للناس وهدى ورحمة لعلهم يتذكرون","އަދި ހަމަކަށަވަރުން، އިހުގެ ޖީލުތައް ހަލާކު ކުރެއްވުމަށްފަހުގައި، ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް ފޮތް ދެއްވީމެވެ. (އެއީ) މީސްތަކުންނަށް ހުރި އިބްރަތެއް ކަމުގައްޔާއި، ތެދުމަގެއް ކަމުގައްޔާއި، ރަހުމަތެއް ކަމުގައެވެ. (އެއީ) އެއުރެން ހަނދުމަކުރުމަށްޓަކައެވެ.","",""],["","","","وما كنت بجانب الغربي إذ قضينا إلى موسى الأمر وما كنت من الشاهدين","(އޭ މުޙައްމަދުގެފާނެވެ!) އަދި ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް އަމުރުތައް ކަނޑައެޅުއްވިހިނދު (ފަރުބަދައިގެ) ހުޅަނގުފަރާތުގައި ކަލޭގެފާނު ވަޑައިގެން ނުވަމުއެވެ. އަދި (އެތަނަށް) ޙާޒިރުުވި މީހުންގެ ތެރެޔަކުންވެސް ކަލޭގެފާނު ވެވަޑައިގެން ނުވަމުއެވެ.","",""],["","","","ولكنا أنشأنا قرونا فتطاول عليهم العمر وما كنت ثاويا في أهل مدين تتلو عليهم آياتنا ولكنا كنا مرسلين","އެހެނެއްކަމަކު (އޭގެފަހަށް) ތިމަންރަސްކަލާނގެ އެތައް ޖީލެއްގެ މީހުން އުފެއްދެވީމެވެ. ފަހެ، އެއުރެންގެ މައްޗަށް ޒަމާން ދިގުވެގެންދިޔައެވެ. އަދި މަދްޔަންގެ އަހުލުވެރިންގެ ތެރޭގައި އެއުރެންނަށް ތިމަންރަސްކަލާނގެ އާޔަތްތައް ކިޔަވައި ދެއްވާކަށް ކަލޭގެފާނު ނުހުންނަވަމުއެވެ. އެހެނެއްކަމަކު، ކަލޭގެފާނު ރަސޫލުކަމާއިގެން ފޮނުއްވީ (އަދި އެ ޚަބަރުތައް ކަލޭގެފާނަށް އެންގެވީ) ތިމަންރަސްކަލާނގެއެވެ.","",""],["","","","وما كنت بجانب الطور إذ نادينا ولكن رحمة من ربك لتنذر قوما ما أتاهم من نذير من قبلك لعلهم يتذكرون","(އޭ މުޙައްމަދުގެފާނެވެ!) އަދި ތިމަންރަސްކަލާނގެ (މޫސާގެފާނަށް) ނިދާއިއްވެވިހިނދު، ޠޫރު ފަރުބަދައިގެ ކައިރިއަކު ކަލޭގެފާނު ވަޑައިގެންނުވަމުއެވެ. އެހެނެއްކަމަކު (ކަލޭގެފާނު ފޮނުއްވާފައިވަނީ) ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތު ންވާ ރަހުމަތެއް ކަމުގައެވެ. (އެއީ) ކަލޭގެފާނުގެ ކުރީގައި އެއުރެންގެގާތަށް އިންޒާރުކުރައްވާ ރަސޫލަކު ވަޑައިގެންފައިނުވާ ގައުމެއްގެ މީހުންނަށް އިންޒާރުކުރެއްވުމަށްޓަކައެވެ. (އެއީ) އެއުރެން ހަނދުމަކުރުމަށްޓަކައެވެ.","",""],["","","","ولولا أن تصيبهم مصيبة بما قدمت أيديهم فيقولوا ربنا لولا أرسلت إلينا رسولا فنتبع آياتك ونكون من المؤمنين","އަދި އެއުރެންގެ އަތްތަކުން އިސްކުޅަ ޢަމަލުތަކުގެ ސަބަބުން އެއުރެންނަށް މުސީބަތެއް ނުޖެހޭނެނަމަ (ތިމަންރަސްކަލާނގެ ރަސޫލު ބޭކަލުން ނުފޮނުއްވީމުހެވެ.) ފަހެ، އޭރުން އެއުރެން ބުނާނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެންގެ ގާތަށް އިބަރަސްކަލާނގެ ރަސޫލަކު ނުފޮނުއްވީ ކީއްވެގެންތޯއެވެ؟ އޭރުން އަޅަމެން އިބަރަސްކަލާނގެ އާޔަތްތަކަށް ތަބާވެ، މުއުމިނުންގެ ތެރެއިން ވެއްޖައީމުހެވެ.","",""],["","","","فلما جاءهم الحق من عندنا قالوا لولا أوتي مثل ما أوتي موسى أولم يكفروا بما أوتي موسى من قبل قالوا سحران تظاهرا وقالوا إنا بكل كافرون","ފަހެ، ތިމަންރަސްކަލާނގެ ހަޒުރަތުން އެއުރެންގެގާތަށް ހައްގު ތެދުމަގު އައިހިނދު (އެބަހީ: ތެދުމަގާއިގެން މުޙައްމަދުގެފާނު ވަޑައިގަތްހިނދު) އެއުރެން ބުނޫއެވެ. މޫސާގެފާނަށް ދެއްވިފަދަ މުއުޖުޒާތް ތަކެއް އެކަލޭގެފާނަށް ނުދެއްވީ ކީއްވެގެން ހެއްޔެވެ؟ މީގެކުރިން މޫސާގެފާނަށް ދެއްވި އެއްޗަކަށް، އެއުރެން ފަހެ، ކާފިރު ވެފައެއް ނުވޭހެއްޔެވެ؟ އެއުރެން ބުނޫއެވެ. (ތައުރާތާއި ގުރްއާނަކީ) އެކަތި އަނެކައްޗަށް ވާގިވެރިވާ ދެ ޖާދޫއެކެވެ. އަދި އެއުރެން ބުނޫއެވެ. ހަމަކަށަވަރުން، އެއިންކޮންމެ އެއްޗަކަށް ތިމަންމެން ކާފިރު ވަމުއެވެ.","",""],["","","","قل فأتوا بكتاب من عند الله هو أهدى منهما أتبعه إن كنتم صادقين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ތެދުވެރިން ކަމުގައިވާނަމަ، ފަހެ، އެ ދެފޮތަށްވުރެ ތެދުމަގު ދެއްކުންބޮޑު ފޮތެއް، ތިމަންކަލޭގެފާނު އެއަށް ތަބާ ވުމަށް، ﷲގެ ހަޒުރަތުން ތިޔަބައިމީހުން ނިކަން ގެނެސްބަލާށެވެ!","",""],["","","","فإن لم يستجيبوا لك فاعلم أنما يتبعون أهواءهم ومن أضل ممن اتبع هواه بغير هدى من الله إن الله لا يهدي القوم الظالمين","ފަހެ، އެއުރެން ކަލޭގެފާނަށް އިޖާބަ ނުދިންނަމަ (އެބަހީ: ކަލޭގެފާނު އެއުރެންގެ ކިބައިން އެދިވަޑައިގެންނެވި ކަންތައް، އެއުރެންނަށް ނުކުރެވިއްޖެނަމަ) ފަހެ، ދެނެވަޑައިގަންނަވާށެވެ! ހަމަކަށަވަރުން، އެއުރެން އެ ތަބާ ވަނީ، ހަމައެކަނި އެއުރެންގެ (ނުބައި) އެދުންތަކަށެވެ. އަދި ﷲގެ ހަޒުރަތުން ތެދުމަގަކާނުލައި، އެމީހެއްގެ އަމިއްލަ އެދުމަށް ތަބާ ވީ މީހަކަށްވުރެ މަގުފުރެދުންބޮޑީ ކާކުހެއްޔެވެ؟ ހަމަކަށަވަރުން، އަނިޔާވެރި ބަޔަކަށް ﷲ ތެދުމަގެއް ނުދައްކަވާނެތެވެ.","",""],["","","","ولقد وصلنا لهم القول لعلهم يتذكرون","އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ވަހީގެ ބަސްފުޅު (އެބަހީ: ގުރްއާން) ވިދިވިދިގެން ބާވައިލައްވައި، އެއުރެންނާ ހަމަޔަށް ގެނެސްދެއްވީމެވެ. (އެއީ) އެއުރެން ހަނދުމަކުރުމަށްޓަކައެވެ.","",""],["","","","الذين آتيناهم الكتاب من قبله هم به يؤمنون","މީގެކުރިން ތިމަންރަސްކަލާނގެ ފޮތްދެއްވި މީހުން (އެބަހީ: ތައުރާތާއި އިންޖީލުގެ އަހުލުވެރިންކުރެ އިސްލާމްވި މީހުން) އެފޮތަށް (އެބަހީ: ގުރްއާނަށް) އީމާން ވެއެވެ.","",""],["","","","وإذا يتلى عليهم قالوا آمنا به إنه الحق من ربنا إنا كنا من قبله مسلمين","އަދި އެއުރެންނަށް އެ ފޮތް ކިޔަވައިދެވޭހިނދު އެއުރެން ބުނެތެވެ. ތިމަންމެން އެ ފޮތަށް އީމާން ވެއްޖައީމުއެވެ. ހަމަކަށަވަރުން، އެއީ ތިމަންމެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައި ހައްގު ތެދެވެ. ހަމަކަށަވަރުން، ތިމަންމެން މީގެކުރީގައިވެސް މުސްލިމުން ކަމުގައިވީމުއެވެ.","",""],["","","","أولئك يؤتون أجرهم مرتين بما صبروا ويدرءون بالحسنة السيئة ومما رزقناهم ينفقون","އެއުރެންނީ، ކެތްތެރިވިކަމަށްޓަކައި، އެއުރެންނަށް ދެފަހަރަށް ދަރުމަ ދެއްވާނޭ މީހުންނެވެ. އަދި އެއުރެން ހެއުކަންތައް މެދުވެރިކޮށް ނުބައިކަންތައް ދިފާޢުކުރެތެވެ. އަދި ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްވި ތަކެތިން އެއުރެން ހޭދަކުރެތެވެ.","",""],["","","","وإذا سمعوا اللغو أعرضوا عنه وقالوا لنا أعمالنا ولكم أعمالكم سلام عليكم لا نبتغي الجاهلين","އަދި އެއުރެންނަށް ބޭކާރު ވާހަކަ އިވޭހިނދު، އެއުރެން އެއިން އެއްކިބާވެގަނެތެވެ. އަދި އެއުރެން ބުނެތެވެ. ތިމަންމެންނަށް، ތިމަންމެންގެ ޢަމަލު ތަކެވެ. އަދި ތިޔަބައިމީހުންނަށް ތިޔަބައިމީހުންގެ ޢަމަލު ތަކެވެ. ތިމަންމެންނާ ތިޔަބައިމީހުންނާ ވަތްކެވެ. (އެހެނީ) ތިމަންމެން ޖާހިލުންނާއެކު އުޅުމަކަށް ނޭދެމުއެވެ.","",""],["","","","إنك لا تهدي من أحببت ولكن الله يهدي من يشاء وهو أعلم بالمهتدين","ހަމަކަށަވަރުން، ކަލޭގެފާނު އެދިވަޑައިގަންނަވާހާ މީހަކަށް ކަލޭގެފާނަކަށް ތެދުމަގެއް ނުދެއްކެވޭނެތެވެ. އެހެނެއްކަމަކު، ﷲ، އެކަލާނގެ އިރާދަކުރެއްވި އަޅަކަށް ތެދުމަގު ދައްކަވަތެވެ. އަދި ތެދުމަގު ލިބެނިވި މީހުން މޮޅަށް ދެނެވޮޑިގެންވަނީ އެކަލާނގެއެވެ.","",""],["","","","وقالوا إن نتبع الهدى معك نتخطف من أرضنا أولم نمكن لهم حرما آمنا يجبى إليه ثمرات كل شيء رزقا من لدنا ولكن أكثرهم لا يعلمون","އަދި އެއުރެން ބުނޫއެވެ. ތިމަންމެން ކަލޭގެފާނާއެކު ތެދުމަގަށް ތަބާ ވެއްޖެނަމަ، ތިމަންމެން ރަށުން ތިމަންމެން ޖަހައިގަނެވޭ ހުށްޓެވެ. އަމާން ކަން ލިބިގެންވާ ހަރަމެއް ތިމަންރަސްކަލާނގެ އެއުރެންނަށްޓަކައި ނުލައްވަންހެއްޔެވެ؟ އެތަނަށް ތިމަންރަސްކަލާނގެ ހަޒުރަތުން ލިބެނިވި ރިޒްގެއްގެ ގޮތުގައި، ހުރިހާ ބާވަތެއްގެ މޭވާ ގެނެވެއެވެ. އެހެނެއްކަމަކު، އެއުރެންކުރެ ގިނަމީހުން އެކަމެއް ނުދަނެތެވެ.","",""],["","","","وكم أهلكنا من قرية بطرت معيشتها فتلك مساكنهم لم تسكن من بعدهم إلا قليلا وكنا نحن الوارثين","އަދި އެއުރެންނަށް ދެއްވި ދިރިއުޅުމުގެ ތަނަވަސްކަމުގެ މައްޗަށް ކިބުރުވެރިވެގެން އުޅުނު ކިތައްކިތައް ރަށުގެ އަހުލުވެރިން ތިމަންރަސްކަލާނގެ ހަލާކުކޮށްލެއްވިން ހެއްޔެވެ؟ ފަހެ، އެއުރެންގެ ގެދޮރު (ފެންނާން) އެހުރީއެވެ. ވަރަށްމަދު ހިނދުކޮޅެއްގައި މެނުވީ، އެއިން ގެއެއްގައި އެއުރެންނަށްފަހު، މީހަކަށް ނޫޅެވެތެވެ. އަދި ދެމިހުންނަނިވި ވާރުތަވެރިޔަކީވެސް ތިމަންރަސްކަލާނގެއެވެ. (އެބަހީ: އެންމެހާ ތަކެތި ފަނާވެދިއުމަށްފަހުވެސް ދިރިދެމިވޮޑިގެންވަނީ ތިމަންރަސްކަލާނގެއެވެ.)","",""],["","","","وما كان ربك مهلك القرى حتى يبعث في أمها رسولا يتلو عليهم آياتنا وما كنا مهلكي القرى إلا وأهلها ظالمون","އަދި ރަށްތަކުގެ ތެރެއިން މައިރަށަށް، ތިމަންރަސްކަލާނގެ އާޔަތްތައް ކިޔަވައި ވިދާޅުވެ ދެއްވާނޭ ރަސޫލަކު ފޮނުއްވައިފުމަށް ދާނދެން ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެރަށްތައް ހަލާކުކޮށެއް ނުލައްވަތެވެ. އެތަންތާނގެ އަހުލުވެރިން އަނިޔާވެރިވާ ޙާލުގައި މެނުވީ، ތިމަންރަސްކަލާނގެ އެރަށްތައް ހަލާކެއް ނުކުރައްވަމެވެ.","",""],["","","","وما أوتيتم من شيء فمتاع الحياة الدنيا وزينتها وما عند الله خير وأبقى أفلا تعقلون","އަދި ތިޔަބައިމީހުންނަށް ދެއްވި ކޮންމެ އެއްޗަކީ، ދުނިޔޭގެ ދިރިއުޅުމުގެ ވަގުތީ އުފަލެކެވެ. އަދި އެތާނގެ ޒީނަތްތެރިކަމެވެ. އަދި ﷲގެ ހަޒުރަތު ގައިވާ ތަކެތި ހެޔޮކަން ބޮޑުވެފައި، ދެމިހުރުން ބޮޑެވެ. ފަހެ، ތިޔަބައިމީހުންނަކަށް ނުވިސްނޭ ހެއްޔެވެ؟","",""],["","","","أفمن وعدناه وعدا حسنا فهو لاقيه كمن متعناه متاع الحياة الدنيا ثم هو يوم القيامة من المحضرين","ފަހެ، އެމީހަކަށް ރިވެތިވެގެންވާ ވައުދަކުން ތިމަންރަސްކަލާނގެ ވައުދުކުރައްވާފައިވާ، އަދި އެ ވައުދުކުރެއްވެވިކަމެއް ލިބެނިވި މީހަކީ، ދުނިޔޭގެ ދިރިއުޅުމުގެ ވަގުތީ އުފާ ތިމަންރަސްކަލާނގެ އެމީހަކަށް ދެއްވި މީހަކާ އެއްފަދަ މީހެއް ހެއްޔެވެ؟ ދެން ގިޔާމަތް ދުވަހުން، އެމީހާވާހުށީ (އުގޫބާތް ލިބުމަށް) ޙާޒިރުުކުރައްވާ މީހުންގެ ތެރެއިންނެވެ.","",""],["","","","ويوم يناديهم فيقول أين شركائي الذين كنتم تزعمون","އަދި އެއުރެންނަށް (އެބަހީ: މުޝްރިކުންނަށް) އެކަލާނގެ ނިދާ އިއްވަވާ ދުވަސް (ހަނދުމަކުރާށެވެ!) ފަހެ، އެކަލާނގެ (އެދުވަހުން އެއުރެން ދެރަކޮށްލެއްވުމުގެގޮތުން) ވަހީކުރައްވާނެތެވެ. ތިމަންރަސްކަލާނގެއަށްވާ ޝަރީކުން ކަމުގައި ތިޔަބައިމީހުން ހީކޮށްގެން އުޅުނު ތަކެތި ކޮބައިހެއްޔެވެ؟","",""],["","","","قال الذين حق عليهم القول ربنا هؤلاء الذين أغوينا أغويناهم كما غوينا تبرأنا إليك ما كانوا إيانا يعبدون","އެއުރެންގެ މައްޗަށް (ކޯފާގެ) ބަސްފުޅު ހައްގު ވީ މީހުން ދަންނަވާނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! މިތިބީ އަޅަމެން މަގުފުރެއްދި މީހުންނެވެ. އަޅަމެން، އެއުރެން މަގުފުރެއްދީ، އަޅަމެންވެސް މަގުފުރެދުނު ފަދައިންނެވެ. އިބަރަސްކަލާނގެ ހަޒުރަތަށް އެއުރެންގެ ކިބައިން އަޅަމެން ބަރީއަވެއްޖައީމުއެވެ. އެއުރެން އަޅުކަންކޮށް އުޅުނީ އަޅަމެންނަކަށް ނޫނެވެ.","",""],["","","","وقيل ادعوا شركاءكم فدعوهم فلم يستجيبوا لهم ورأوا العذاب لو أنهم كانوا يهتدون","އަދި (ދެރަކޮށްލެއްވުމުގެގޮތުން) އަންގަވާ ހުށްޓެވެ. ތިޔަބައިމީހުންގެ ޝަރީކުންނަށް ތިޔަބައިމީހުން ގޮވާށެވެ! ފަހެ، އެއުރެން އެ ޝަރީކުންނަށް ގޮވާނެތެވެ. އެ ޝަރީކުން އެއުރެންނަކަށް އިޖާބައެއް ނުދޭނެތެވެ. އަދި އެއުރެންނަށް އަޒާބު ފެންނަ ހުށްޓެވެ. އެހިނދު، އެއުރެންނަށް ތެދުމަގު ލިބުނުނަމަ، ކިހާރަނގަޅުހޭ އެއުރެން ހިތަށް އަރާނެތެވެ.","",""],["","","","ويوم يناديهم فيقول ماذا أجبتم المرسلين","އަދި އެއުރެންނަށް (އެބަހީ: މުޝްރިކުންނަށް) އެކަލާނގެ ނިދާ އިއްވަވާ ދުވަސް (ހަނދުމަކުރާށެވެ!) ފަހެ، އެކަލާނގެ ވަހީކުރައްވާނެތެވެ. (ތިމަންރަސްކަލާނގެ ފޮނުއްވި) ރަސޫލުންނަށް ތިޔަބައިމީހުން ދިނީ ކޮން ޖަވާބެއް ހެއްޔެވެ؟","",""],["","","","فعميت عليهم الأنباء يومئذ فهم لا يتساءلون","ފަހެ، އެދުވަހުން (ރަނގަޅު ޖަވާބެއް ދިނުމަށް) ޚަބަރުތައް އެއުރެންގެ މައްޗަށް ފަރުދާވެގެން ހިނގައިދާހުށްޓެވެ. ފަހެ، އެއުރެން (ހައިރާން ވެފައިވާލެއް ބޮޑުކަމުން) އެކަކު އަނެކަކާ ސުވާލު ވެސް ކޮށްނުލާނެތެވެ.","",""],["","","","فأما من تاب وآمن وعمل صالحا فعسى أن يكون من المفلحين","ފަހެ، ތައުބާވެ، އީމާންވެ، ސާލިހު ޢަމަލުކުޅަމީހާ ދަންނާށެވެ! ފަހެ، އޭނާ ކާމިޔާބުވާ މީހުންގެ ތެރެއިންވުންގާތެވެ.","",""],["","","","وربك يخلق ما يشاء ويختار ما كان لهم الخيرة سبحان الله وتعالى عما يشركون","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، އެކަލާނގެ އިރާދަކުރައްވާ އެއްޗެއް ހައްދަވަތެވެ. އަދި އެކަލާނގެ ރުއްސަވައިފި އަޅަކު (ނަބީކަމަށް) ޚިޔާރުކުރައްވަތެވެ. އެއުރެންނަކަށް ޚިޔާރުކުރުމެއް ނެތެވެ. އެއުރެން ޝަރީކުކުރާ ތަކެތިން ﷲ ހުސްތާހިރުވެ މަތިވެރިވެ ވޮޑިގެންވެއެވެ.","",""],["","","","وربك يعلم ما تكن صدورهم وما يعلنون","އަދި އެއުރެންގެ ހިތްތަކުގައި ވަންހަނާކުރާ ތަކެއްޗާއި، އެއުރެން ފާޅުކުރާ ތަކެތި، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","وهو الله لا إله إلا هو له الحمد في الأولى والآخرة وله الحكم وإليه ترجعون","އަދި އެކަލާނގެއީ، ﷲއެވެ. އެކަލާނގެ މެނުވީ، އެހެން އިލާހަކު ނުވެއެވެ. ދުނިޔެއާއި، އާޚިރަތުގައި، އެންމެހާ ތައުރީފާއި، ޘަނާ މިލްކުވެގެންވަނީ އެކަލާނގެއަށެވެ. އަދި ނިޔާކުރެއްވުން މިލްކުވެގެންވަނީވެސް އެކަލާނގެއަށެވެ. އަދި ތިޔަބައިމީހުން ރުޖޫއަކުރައްވާހުށީ، އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","قل أرأيتم إن جعل الله عليكم الليل سرمدا إلى يوم القيامة من إله غير الله يأتيكم بضياء أفلا تسمعون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން (ތިމަންކަލޭގެފާނަށް) ނިކަން ޚަބަރު ދީ ބަލާށެވެ! ތިޔަބައިމީހުންގެ މައްޗަށް ރޭގަނޑު (ބަދަލެއްނުވެ) ގިޔާމަތް ދުވަހާ ޖެހެންދެން ދެމިއޮންނަ އެއްޗެއް ކަމުގައި ﷲ ލެއްވިނަމަ، ތިޔަބައިމީހުންނަށް (ދުވާލުގެ) އަލިކަން ގެނެސްދޭނީ، ﷲ ފިޔަވައި އެހެން ކޮން އިލާހެއް ހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުންނަށް ނީވެނީހެއްޔެވެ؟","",""],["","","","قل أرأيتم إن جعل الله عليكم النهار سرمدا إلى يوم القيامة من إله غير الله يأتيكم بليل تسكنون فيه أفلا تبصرون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން (ތިމަންކަލޭގެފާނަށް) ނިކަން ޚަބަރު ދީ ބަލާށެވެ! ތިޔަބައިމީހުންގެ މައްޗަށް ދުވާލު (ބަދަލެއްނުވެ) ގިޔާމަތް ދުވަހާ ޖެހެންދެން ދެމިއޮންނަ އެއްޗެއް ކަމުގައި ﷲ ލެއްވިނަމަ، ތިޔަބައިމީހުން އަރާމުކުރަން ތިބޭނޭ ރޭގަނޑެއް ތިޔަބައިމީހުންނަށް ގެނެސްދޭނީ، ﷲ ފިޔަވައި އެހެން ކޮން އިލާހެއް ހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުންނަށް ނުފެންނަނީ ހެއްޔެވެ؟","",""],["","","","ومن رحمته جعل لكم الليل والنهار لتسكنوا فيه ولتبتغوا من فضله ولعلكم تشكرون","އެކަލާނގެ ރަހުމަތް ވަންތަކަމުން ތިޔަބައިމީހުން އަރާމުކުރުމަށާއި، އެކަލާނގެ ފަޟްލު ވަންތަކަމުން ދެއްވާ ރިޒްގު ހޯދުމަށް މަސައްކަތް ކުރުމަށް، އެކަލާނގެ ތިޔަބައިމީހުންނަށްޓަކައި، ރޭގަނޑާއި، ދުވާލު ލެއްވިއެވެ. (އެއީ) ތިޔަބައިމީހުން ޝުކުރުކުރުމަށްޓަކައެވެ.","",""],["","","","ويوم يناديهم فيقول أين شركائي الذين كنتم تزعمون","އަދި އެއުރެންނަށް (އެބަހީ: މުޝްރިކުންނަށް) އެކަލާނގެ ނިދާ އިއްވަވާ ދުވަސް (ހަނދުމަކުރާށެވެ!) ފަހެ، އެކަލާނގެ (އެދުވަހުން އެއުރެން ދެރަކޮށްލެއްވުމުގެގޮތުން) ވަހީކުރައްވާނެތެވެ. ތިމަންރަސްކަލާނގެއަށްވާ ޝަރީކުން ކަމުގައި ތިޔަބައިމީހުން ހީކޮށްއުޅުނު ތަކެތި ކޮބައިހެއްޔެވެ؟","",""],["","","","ونزعنا من كل أمة شهيدا فقلنا هاتوا برهانكم فعلموا أن الحق لله وضل عنهم ما كانوا يفترون","އަދި ތިމަންރަސްކަލާނގެ ކޮންމެ އުއްމަތަކުން ހެކިވާނޭ މީހަކު ނެރުއްވާ ހުށީމެވެ. (އެއީ އެ އުއްމަތްގެ ނަބިއްޔާއެވެ.) ދެން ތިމަންރަސްކަލާނގެ (އުއްމަތްތަކަށް) ވަހީކުރައްވާ ހުށީމެވެ. ތިޔަބައިމީހުންގެ ދަލީލު ތިޔަބައިމީހުން ގެންނާށެވެ! ފަހެ، އެހިނދު (އިލާހު ވަންތަކަން) ހައްގު ވެގެންވަނީ (ހަމައެކަނި) ﷲއަށްކަން އެއުރެންނަށް އެނގޭނެތެވެ. އަދި އެއުރެން އަމިއްލައަށް ހަދައިގެން އުޅުނު ދޮގުތައް އެއުރެންނަށް ގެއްލި ހިނގައިދާނެތެވެ.","",""],["","","","إن قارون كان من قوم موسى فبغى عليهم وآتيناه من الكنوز ما إن مفاتحه لتنوء بالعصبة أولي القوة إذ قال له قومه لا تفرح إن الله لا يحب الفرحين","ހަމަކަށަވަރުން، ގާރޫނަކީ، މޫސާގެފާނުގެ ގައުމުގެމީހުންގެ ތެރެއިންވީ މީހެކެވެ. ފަހެ، އޭނާ އެއުރެންގެ މައްޗަށް ބޮޑާވެގަތެވެ. އަދި ތިމަންރަސްކަލާނގެ އޭނާއަށް ގިނަވެގެންވާ (މުދާތަކުގެ) ޚަޒާނާތައް ދެއްވީމެވެ. ހަމަކަށަވަރުން، ވަރުގަދަ ޖަމާއަތެއްގެ މީހުންނަށް، އެ ޚަޒާނާތަކުގެ ތަޅުދަނޑިތައް އުފުލުންވަނީ ބުރަވެފައެވެ. އޭނާގެ ގައުމުގެމީހުން އޭނާއަށް ބުނިހިނދެވެ. (ކިބުރުވެރިވުމުގެގޮތުން) އުފާ ނުކުރާށެވެ! ހަމަކަށަވަރުން، ބޮޑާވުމުގެގޮތުން އުފާކުރާ މީހުންދެކެ ﷲ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["","","","وابتغ فيما آتاك الله الدار الآخرة ولا تنس نصيبك من الدنيا وأحسن كما أحسن الله إليك ولا تبغ الفساد في الأرض إن الله لا يحب المفسدين","އަދި ތިބާޔަށް ﷲ ދެއްވި ތަކެތިން (ހެޔޮގޮތުގައި ހޭދަކުރުމުން) އާޚިރަތްގެ ގޮވައްޗަށް އެދޭށެވެ! (އެބަހީ: އާޚިރަތްގެ ދިންނެވުމާއި، ރަހުމަތާއި، ސަވާބަށް އެދޭށެވެ!) އަދި ދުނިޔެއިން ތިބާޔަށް ލިބެންވީބައި ހަނދާން ނައްތައިނުލާށެވެ! އަދި ﷲ، ތިބާޔަށް އިހްސާން ތެރިވެވޮޑިގަތް ފަދައިން، ތިބާވެސް (ﷲގެ އަޅުތަކުންނަށް) އިހްސާން ތެރިވާށެވެ! އަދި ބިމުގައި ފަސާދަ އުފެއްދުމަށް ތިބާ އެދިނޫޅޭށެވެ! ހަމަކަށަވަރުން، ފަސާދަކުރާ މީހުންދެކެ، ﷲ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["","","","قال إنما أوتيته على علم عندي أولم يعلم أن الله قد أهلك من قبله من القرون من هو أشد منه قوة وأكثر جمعا ولا يسأل عن ذنوبهم المجرمون","އޭނާ ބުންޏެވެ. ތިމަންނާއަށް އެ މުދާ ލިބުނުކަން ކަށަވަރީ، ތިމަންގެ ކިބައިގައިވާ އިލްމުވެރިކަމަކުންނެވެ. ހަމަކަށަވަރުން، އޭނާގެ ކުރިން އިސްވެދިޔަ ޖީލު ތަކުން އޭނާޔަށްވުރެ މާވަރުގަދަ އަދި މުދާ ގިނަމީހުން ﷲ ހަލާކުކުރެއްވިކަން އޭނާޔަށް ނޭނގެނީހެއްޔެވެ؟ އަދި ކުށްވެރިންނަކަށް، އެއުރެންގެ ފާފަތަކާމެދު ސުވާލެއް ނުކުރައްވާނެތެވެ. (އެބަހީ: އެއުރެންނާ ސުވާލުކުރެއްވުމުގެ ބޭނުމެއްނެތެވެ. ﷲ ހުރިހާކަމެއް ދެނެވޮޑިގެންވެތެވެ.)","",""],["","","","فخرج على قومه في زينته قال الذين يريدون الحياة الدنيا يا ليت لنا مثل ما أوتي قارون إنه لذو حظ عظيم","ފަހެ، އޭނާ (އެބަހީ: ގާރޫނު) އޭނާގެ މުއްސަނދިކަމާއި ޒީނަތްތެރިކަމާއެކު، އޭނާގެ ގައުމުގެ ތެރެޔަށް ނުކުތެވެ. ދުނިޔޭގެ ދިރިއުޅުން އެދޭމީހުން ބުނޫއެވެ. ގާރޫނަށް ލިބުނުފަދަ މުއްސަނދިކަމެއް ތިމަންމެންނަށްވެސް ލިބުނުނަމަ، ކިހާރަނގަޅުވީސްހެއްޔެވެ؟ ހަމަކަށަވަރުން، އޭނާޔަކީ ބޮޑުވެގެންވާ ނަސީބެއްގެ ވެރިޔެއްކަން ކަށަވަރެވެ.","",""],["","","","وقال الذين أوتوا العلم ويلكم ثواب الله خير لمن آمن وعمل صالحا ولا يلقاها إلا الصابرون","އަދި އިލްމު ލިބިގެންވާ މީހުން ބުނޫއެވެ. ތިޔަބައިމީހުންނަށް ހަލާކުހުށްޓެވެ. އީމާންވެ ސާލިހު ޢަމަލުކުޅަމީހަކަށް، ﷲގެ ސަވާބު (ގާރޫނުގެ މުދާވެރިކަމަށްވުރެ) މާހެޔޮކަން ބޮޑެވެ. އަދި ކެތްތެރިންނަށް މެނުވީ، އެ ދަރަޖައެއް ނުލިބޭނެތެވެ.","",""],["","","","فخسفنا به وبداره الأرض فما كان له من فئة ينصرونه من دون الله وما كان من المنتصرين","ފަހެ، ތިމަންރަސްކަލާނގެ އޭނާއާއި، އޭނާގެ (ޚަޒާނާ ތަކާއި) ގެއާއެކުގައި، ބިންގަނޑު ގަންބަވައިގެންނެވީމެވެ. ފަހެ، ﷲއާ ދެކޮޅަށް އޭނާޔަށް ނަސްރު ދޭނޭ އެއްވެސްބަޔެއް ނުވިއެވެ. އަދި ނަސްރު ލިބޭނޭ މީހުންގެ ތެރެއިންވެސް އޭނާ ނުވިއެވެ.","",""],["","","","وأصبح الذين تمنوا مكانه بالأمس يقولون ويكأن الله يبسط الرزق لمن يشاء من عباده ويقدر لولا أن من الله علينا لخسف بنا ويكأنه لا يفلح الكافرون","އަދި އިއްޔެ އޭނާގެ ދަރަޖައަށް (އެބަހީ: ގާރޫނުގެ މުދާވެރިކަމަށާއި ދަރަޖައަށް) އެދުނުމީހުން ބުނާކަމުގައިވިއެވެ. ކަލެޔަކަށް ނުފެނޭހެއްޔެވެ؟ ﷲ، އެކަލާނގެ އަޅުތަކުންކުރެ އިރާދަކުރެއްވި އަޅަކަށް ރިޒްގު ތަނަވަސް ކޮށްދެއްވައި، އަދި (އެކަލާނގެ އިރާދަކުރެއްވި އަޅަކަށް ރިޒްގު) ދަތިކުރައްވަތެވެ. ﷲ، އަޅަމެންގެ މައްޗަށް ދަރުމަވަންތަވެ ވޮޑިނުގަތްނަމަ، އަޅަމެންވެސް ގަންބަވައިގަންނަވައިފީހެވެ. ކަލެޔަކަށް ނުފެނޭހެއްޔެވެ؟ ކާފިރުންނެއް ނުދިނޭނެތެވެ.","",""],["","","","تلك الدار الآخرة نجعلها للذين لا يريدون علوا في الأرض ولا فسادا والعاقبة للمتقين","އެއީ އާޚިރަތްގެ (ނިއުމަތްގެ) ގޮވައްޗެވެ. އެ ގޮވަތި ތިމަންރަސްކަލާނގެ ލައްވާހުށީ ބިމުގައި ބޮޑާވެގަތުމެއް، އަދި ފަސާދަކުރުމެއްވިޔަސް ނޭދޭ މީހުންނަށެވެ. އަދި ހެޔޮނިމުންވަނީ ތަގުވާވެރިންނަށެވެ.","",""],["","","","من جاء بالحسنة فله خير منها ومن جاء بالسيئة فلا يجزى الذين عملوا السيئات إلا ما كانوا يعملون","ހެޔޮކަމާއިގެން އަތުވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް އެއަށްވުރެ ހެޔޮވެގެންވާ ސަވާބު (އާޚިރަތުގައި) ހުށްޓެވެ. އަދި ނުބައިކަމާއިގެން އަތުވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، ނުބައިކަންތައް ކުރިމީހުންނަށް އެއުރެން ކޮށްއުޅުނު ޢަމަލުތަކަށް މެނުވީ ޖަޒާއެއް ނުލިބޭހުށްޓެވެ.","",""],["","","","إن الذي فرض عليك القرآن لرادك إلى معاد قل ربي أعلم من جاء بالهدى ومن هو في ضلال مبين","ހަމަކަށަވަރުން، ކަލޭގެފާނަށް ގުރްއާން ބާވައިލެއްވި ރަސްކަލާނގެ ކަލޭގެފާނުގެ އުފަން ރަށަށް (އެބަހީ: މައްކާއަށް) ކަލޭގެފާނު އަނބުރާ ފޮނުއްވާ ހުށްޓެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތެދުމަގާއިގެން އައިމީހާއާއި، ފާޅުވެގެންވާ ފުރެދުމެއްގައިވާމީހާ، އެންމެ މޮޅަށް ދެނެވޮޑިގެންވަނީ، އަހުރެންގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["","","","وما كنت ترجو أن يلقى إليك الكتاب إلا رحمة من ربك فلا تكونن ظهيرا للكافرين","އަދި ކަލޭގޭފާނަށް ފޮތް ބާވައިލައްވާނެ ކަމަކަށް ކަލޭގެފާނު އުންމީދެއް ނުކުރައްވަމުއެވެ. އެހެނެއްކަމަކު ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ރަހުމަތުން އެ ފޮތް ކަލޭގެފާނަށް ބާވައިލެއްވިއެވެ. ފަހެ، ކަލޭގެފާނު އެއްވެސް ޙާލެއްގައި ކާފިރުންނަށް ވާގިވެރިޔަކު ކަމުގައި ވެވަޑައިނުގަންނަވާ ހުށިކަމެވެ!","",""],["","","","ولا يصدنك عن آيات الله بعد إذ أنزلت إليك وادع إلى ربك ولا تكونن من المشركين","އަދި ﷲގެ އާޔަތްތައް ކަލޭގެފާނަށް ބާވައިލެއްވުމަށްފަހުގައި، އެ އާޔަތް ތަކުން އެއުރެން ކަލޭގެފާނު އެއްކިބާކުރިޔަ ނުދެއްވާހުށިކަމެވެ! އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ދީނަށް (މީސްތަކުންނަށް) ގޮވައިލައްވާށެވެ! އަދި މުޝްރިކުންގެ ތެރެއިން ކަލޭގެފާނު ވެވަޑައިނުގަންނަވާ ހުށިކަމެވެ!","",""],["","","","ولا تدع مع الله إلها آخر لا إله إلا هو كل شيء هالك إلا وجهه له الحكم وإليه ترجعون","އަދި ﷲއާ އެކުގައި އެހެން އިލާހަކަށް ތިބާ ދުއާ ކޮށް އަޅުކަން ނުކުރާށެވެ! އެކަލާނގެ މެނުވީ، ހައްގު ވެގެން އަޅުކަމެއްވެވޭ އިލާހަކު ނުވެއެވެ. އެކަލާނގެ ޛާތުފުޅު މެނުވީ، އެހެން ހުރިހާ ތަކެއްޗެއް ފަނާވެދާހުށްޓެވެ. ނިޔާކުރެއްވުންވަނީ، ހަމައެކަނި އެކަލާނގެއަށެވެ. އަދި ތިޔަބައިމީހުން ރުޖޫއަކުރައްވާހުށީވެސް އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","بسم الله الرحمن الرحيم الم","ا ل م (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","أحسب الناس أن يتركوا أن يقولوا آمنا وهم لا يفتنون","މީސްތަކުން ތިމަންމެން އީމާން ވެއްޖައީމުއޭ ބުނުމުން، އެއުރެން އިމްތިހާނު ނުކުރައްވައި ދޫކޮށްލައްވާނޭކަމަށް ހީކުރީ ހެއްޔެވެ؟","",""],["","","","ولقد فتنا الذين من قبلهم فليعلمن الله الذين صدقوا وليعلمن الكاذبين","އަދި ހަމަކަށަވަރުން، އެއުރެންގެ ކުރީގެ (އުއްމަތްތަކުގެ) މީހުން، ތިމަންރަސްކަލާނގެ އިމްތިހާނުކުރެއްވީމެވެ. ފަހެ (އީމާންކަމުގައި) ތެދުވެރިވި މީހުން، ހަމަކަށަވަރުން، ﷲ ދެނެވޮޑިގެންވެތެވެ. އަދި ހަމަކަށަވަރުން، ދޮގުވެރިންވެސް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","أم حسب الذين يعملون السيئات أن يسبقونا ساء ما يحكمون","ނުބައި ކަންތައްކުރާމީހުން ތިމަންރަސްކަލާނގެ އުގޫބާތުން ފިލައިގެން ދެވިދާނެކަމަށް ހީކުރީހެއްޔެވެ؟ އެއުރެންކުރާ ހުކުމް ހާދަހާ ނުބައިވެގެންވެއެވެ.","",""],["","","","من كان يرجو لقاء الله فإن أجل الله لآت وهو السميع العليم","ﷲއާ ބައްދަލުވުމަށް އެދޭމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲ ކަނޑައަޅުއްވާފައިވާ އަޖަލު އަންނަހުށްޓެވެ. އެކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ومن جاهد فإنما يجاهد لنفسه إن الله لغني عن العالمين","އަދި ޖިހާދުކުރިމީހާ (ދަންނާށެވެ!) ފަހެ، އޭނާ ޖިހާދުކުރާކަން ކަށަވަރީ، އޭނާގެ އަމިއްލަ ނަފްސަށްޓަކައެވެ. ހަމަކަށަވަރުން، ﷲއީ، އެންމެހާ އާލަމްތައް ފިޔަވައި ފުދިވޮޑިގެންވާ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","والذين آمنوا وعملوا الصالحات لنكفرن عنهم سيئاتهم ولنجزينهم أحسن الذي كانوا يعملون","އަދި އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަމީހުން (ދަންނާށެވެ!) ހަމަކަށަވަރުން ތިމަންރަސްކަލާނގެ އެއުރެންގެ ކިބައިން އެއުރެންގެ ކުށްފާފަފުއްސަވާހުށީމެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެން ކޮށްއުޅުނު ޢަމަލުތަކުގެ އެންމެ ހެޔޮ ޖަޒާ ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްވާހުށީމެވެ.","",""],["","","","ووصينا الإنسان بوالديه حسنا وإن جاهداك لتشرك بي ما ليس لك به علم فلا تطعهما إلي مرجعكم فأنبئكم بما كنتم تعملون","އިންސާނާއަށް އޭނާގެ މައިންބަފައިންނަށް ހެޔޮކޮށް ހިތުމަށް ތިމަންރަސްކަލާނގެ ވަސިއްޔަތްކުރައްވައި، އަމުރުކުރެއްވީމެވެ. އަދި ތިބާޔަށް އެއާމެދު އިލްމެއްލިބިފައި ނުވާ އެއްޗެއް، ތިމަންރަސްކަލާނގެއާ ޝަރީކުކުރުމަށް ތިބާގެ މައްޗަށް އެ ދެމީހުން ގަދައަޅައިފިނަމަ، ފަހެ، އެ ދެމީހުންނަށް ތިބާ ކިޔަމަން ނުވާހުށިކަމެވެ! ތިޔަބައިމީހުން އެނބުރި ދިއުންއޮތީ، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށެވެ. ފަހެ، އޭރުން ތިޔަބައިމީހުން ކޮށްއުޅުނު ކަންތަކުގެ ޚަބަރު ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް އަންގަވާހުށީމެވެ. (އެބަހީ: އެކަންތަކަށް ޖަޒާ ދެއްވާހުށީމެވެ.)","",""],["","","","والذين آمنوا وعملوا الصالحات لندخلنهم في الصالحين","އަދި އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަމީހުން (ދަންނާށެވެ!) ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެން ސާލިހު އަޅުންގެ ތެރެއަށް ވައްދަވާހުށީމެވެ.","",""],["","","","ومن الناس من يقول آمنا بالله فإذا أوذي في الله جعل فتنة الناس كعذاب الله ولئن جاء نصر من ربك ليقولن إنا كنا معكم أوليس الله بأعلم بما في صدور العالمين","ތިމަންމެން އީމާން ވެއްޖައީމުއޭ ދުލުކޮޅުން ބުނާ ބަޔަކު މީސްތަކުންގެ ތެރެއިން ވެއެވެ. ފަހެ، ﷲގެ މަގުގައި އެއިން މީހަކަށް އުނދަގުލެއް ލިބިއްޖެނަމަ، މީސްތަކުންގެ އުނދަގޫތައް ﷲގެ އަޒާބާ އެއްފަދަ ކަމުގައި އޭނާ ހަދަތެވެ. އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ނަސްރެއް އަތުވެއްޖެނަމަ، ހަމަކަށަވަރުން، އެއުރެން ބުނާނެތެވެ. ހަމަކަށަވަރުން، ތިމަންމެންވަނީ، ތިޔަބައިމީހުންނާ އެކުގައެވެ. އާލަމް ތަކުގައިވާ އެންމެންގެ ހިތްތަކުގައިވާހާ އެއްޗެއް ﷲ މޮޅަށް ދެނެވޮޑިގެން ނުވޭހެއްޔެވެ؟","",""],["","","","وليعلمن الله الذين آمنوا وليعلمن المنافقين","އަދި ހަމަކަށަވަރުން، ﷲ، އީމާންވި މީހުން ދެނެވޮޑިގެންވެތެވެ. އަދި ހަމަކަށަވަރުން، އެކަލާނގެ މުނާފިގު ންވެސް ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","وقال الذين كفروا للذين آمنوا اتبعوا سبيلنا ولنحمل خطاياكم وما هم بحاملين من خطاياهم من شيء إنهم لكاذبون","ކާފިރު ވިމީހުން އީމާން ވިމީހުންނަށް ބުނޫއެވެ. ތިޔަބައިމީހުން ތިމަންމެންގެ މަގަށް ތަބާ ވާށެވެ! އަދި ތިޔަބައިމީހުންގެ ކުށްފާފަތައް ތިމަންމެން އުފުލާނޫއެވެ. އެއުރެންގެ ކުށްފާފަތަކުގެ ތެރެއިން އެއްވެސް އެއްޗެއް އުފުލާނޭ ބަޔަކު ކަމުގައި އެއުރެން ނުވެއެވެ. ހަމަކަށަވަރުން، އެއުރެންނީ ދޮގުވެރިންކަން ކަށަވަރެވެ.","",""],["","","","وليحملن أثقالهم وأثقالا مع أثقالهم وليسألن يوم القيامة عما كانوا يفترون","އަދި ހަމަކަށަވަރުން، އެއުރެންގެ އަމިއްލަ ނަފްސުގެ ފާފަތަކާއި އަދި އަމިއްލަ ފާފަތަކާއެކު، އެއުރެން (މަގުފުރެއްދި މީހުން) ގެ ފާފަތައްވެސް އެއުރެން އުފުލާނެތެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެން ހަދައި އުޅުނު ދޮގުތަކާމެދު ގިޔާމަތް ދުވަހުން އެއުރެންނާ ސުވާލުކުރައްވާހުށްޓެވެ.","",""],["","","","ولقد أرسلنا نوحا إلى قومه فلبث فيهم ألف سنة إلا خمسين عاما فأخذهم الطوفان وهم ظالمون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ނޫޙުގެފާނު، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ގާތަށް ރަސޫލުކަމާއިގެން ފޮނުއްވީމެވެ. ފަހެ، އެކަލޭގެފާނު، ފަންސާސް އަހަރު ފިޔަވައި، އެއްހާސް އަހަރު (އެބަހީ: ނުވަސަތޭކަ ފަންސާސް އަހަރު ދީނަށް ގޮވައިލެއްވުމަށް) އެއުރެންގެ ތެރޭގައި ހުންނެވިއެވެ. ފަހެ، އެއުރެން އަނިޔާވެރިންކަމުގައިވާ ޙާލު، ޠޫފާން (ގެ އަޒާބު) އައިސް އެއުރެންނަށް ޖެހުނެވެ.","",""],["","","","فأنجيناه وأصحاب السفينة وجعلناها آية للعالمين","ފަހެ، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނާއި (އެކަލޭގެފާނުގެ) ނާކޮޅުގެ އަހުލުވެރިން ސަލާމަތްކުރެއްވީމެވެ. އަދި އެއީ އާލަމް ތަކަށްވާ އިބްރަތެއްކަމުގައި ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ.","",""],["","","","وإبراهيم إذ قال لقومه اعبدوا الله واتقوه ذلكم خير لكم إن كنتم تعلمون","އަދި އިބްރާހީމްގެފާނު، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް ވިދާޅުވިހިނދު (ހަނދުމަކުރާށެވެ!) ތިޔަބައިމީހުން ﷲއަށް އަޅުކަންކުރާށެވެ! އަދި ތިޔަބައިމީހުން އެކަލާނގެއަށް ތަގުވާވެރިވާށެވެ! ތިޔަބައިމީހުންނަށް އެނގޭކަމުގައިވަނީނަމަ، އެގޮތް ތިޔަބައިމީހުންނަށް ހެޔޮކަން ބޮޑެވެ.","",""],["","","","إنما تعبدون من دون الله أوثانا وتخلقون إفكا إن الذين تعبدون من دون الله لا يملكون لكم رزقا فابتغوا عند الله الرزق واعبدوه واشكروا له إليه ترجعون","ތިޔަބައިމީހުން ﷲ ފިޔަވައި އަޅުކަންކުރާކަން ކަށަވަރީ، ބުދުތަކަކަށެވެ. އަދި ތިޔަބައިމީހުން ހަދަނީ ބުހުތާނު ދޮގެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ﷲ ފިޔަވައި އަޅުކަންކުރާ ތަކެއްޗަކަށް ތިޔަބައިމީހުންނަށް ރިޒްގު ދިނުމެއް މިލްކުވެގެނެއްނުވެތެވެ. ފަހެ، ތިޔަބައިމީހުން ﷲގެ ހަޒުރަތުން ރިޒްގަށް އެދޭށެވެ! އަދި އެކަލާނގެއަށް ތިޔަބައިމީހުން އަޅުކަންކުރާށެވެ! އަދި އެކަލާނގެއަށް ތިޔަބައިމީހުން ޝުކުރުކުރާށެވެ! ތިޔަބައިމީހުން ރުޖޫއަކުރައްވާހުށީ ހަމައެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","وإن تكذبوا فقد كذب أمم من قبلكم وما على الرسول إلا البلاغ المبين","އަދި ތިޔަބައިމީހުން (ތިމަންކަލޭގެފާނު) ދޮގުކުރިޔަސް (ތިމަން ކަލޭގެފާނަކަށް އެކަމަކުން ގެއްލުމެއް ނުލިބޭނެތެވެ. އެހެނީ) ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ކުރިންވެސް އުއްމަތް ތަކެއް (ރަސޫލުން) ދޮގުކޮށްފައިވެއެވެ. އަދި ބަޔާން ވެގެންވާ އިއްވެވުން މެނުވީ، ރަސޫލާގެ މައްޗަކަށް ނުވެއެވެ.","",""],["","","","أولم يروا كيف يبدئ الله الخلق ثم يعيده إن ذلك على الله يسير","އަދި ﷲ، ޚަލްގު ތަކުން ފުރަތަމަ އުފެއްދެވިގޮތާއި ދެން އެއަށްފަހު އަލުން (ދިރުއްވައި) އިއާދަކުރައްވާގޮތް އެއުރެންނަކަށް ނުފެނޭ ހެއްޔެވެ؟ ހަމަކަށަވަރުން، އެކަންތަކަކީ، ﷲއަށް ދާދި ފަސޭހަ ކަމެކެވެ.","",""],["","","","قل سيروا في الأرض فانظروا كيف بدأ الخلق ثم الله ينشئ النشأة الآخرة إن الله على كل شيء قدير","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ބިމުގައި ދަތުރުފަތުރުކޮށް އުޅޭށެވެ! އަދި ﷲ، ޚަލްގު ތަކުން ފުރަތަމަ އުފެއްދެވިގޮތް، ތިޔަބައިމީހުން ވިސްނައިބަލާށެވެ! ދެން އެއަށްފަހު، ﷲ އެންމެފަހުގެ އުފެއްދެވުން އުފައްދަވާނެތެވެ. (އެބަހީ: އަލުން ދިރުއްވައި އިއާދަކުރައްވާނެތެވެ.) ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެ ކަމެއްގެމައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","يعذب من يشاء ويرحم من يشاء وإليه تقلبون","އެކަލާނގެ އިރާދަކުރައްވާ އަޅަކަށް އަޒާބު ދެއްވަތެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވާ އަޅަކަށް ރަހުމަތް ލައްވަތެވެ. އަދި ތިޔަބައިމީހުން (ގިޔާމަތް ދުވަހުން) އެނބުރިދާހުށީ އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","وما أنتم بمعجزين في الأرض ولا في السماء وما لكم من دون الله من ولي ولا نصير","އަދި ތިޔަބައިމީހުންނީ އުޑާއި، ބިމުގައި (ﷲ) ނުކުޅެއްދޭނޭ ބަޔަކު ކަމުގައި ނުވެތެވެ. އަދި ތިޔަބައިމީހުންނަކަށް ﷲ ފިޔަވައި އެއްވެސް އެހީތެރިޔަކު، އަދި ނަސްރު ދޭނޭ މީހަކުވެސް ނުވެތެވެ.","",""],["","","","والذين كفروا بآيات الله ولقائه أولئك يئسوا من رحمتي وأولئك لهم عذاب أليم","އަދި އެއުރެން ﷲގެ އާޔަތް ތަކަށާއި، އެކަލާނގެއާ ބައްދަލުވާނެ ކަމާމެދު ކާފިރުވެ، އިންކާރުކުރި މީހުން (ދަންނާށެވެ!) އެއުރެންނީ، ތިމަންރަސްކަލާނގެ ރަހުމަތުން، ނާއުންމީދު ވެފައިވާ ބަޔެކެވެ. އަދި އެއުރެންނީ އެއުރެންނަށްޓަކައި ވޭންދެނިވި އަޒާބު ހުރި މީހުންނެވެ.","",""],["","","","فما كان جواب قومه إلا أن قالوا اقتلوه أو حرقوه فأنجاه الله من النار إن في ذلك لآيات لقوم يؤمنون","ފަހެ، އެކަލޭގެފާނުގެ (އެބަހީ: އިބްރާހީމްގެފާނުގެ) ގައުމުގެމީހުންގެ ޖަވާބު ކަމުގައި، އެއުރެންގެ މި ބުނުން ނޫނީ ނުވެތެވެ. ތިޔަބައިމީހުން އެކަލޭގެފާނު ގަތުލު ކޮށްލާށެވެ! ނުވަތަ އެކަލޭގެފާނު އަންދައިލާށެވެ! ފަހެ، ﷲ، އެކަލޭގެފާނު އަލިފާނުން ސަލާމަތްކުރެއްވިއެވެ. ހަމަކަށަވަރުން، އީމާންވާ ބަޔަކަށް އެކަންތަކުގައި ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","وقال إنما اتخذتم من دون الله أوثانا مودة بينكم في الحياة الدنيا ثم يوم القيامة يكفر بعضكم ببعض ويلعن بعضكم بعضا ومأواكم النار وما لكم من ناصرين","އެކަލޭގެފާނު (އެބަހީ: އިބްރާހީމްގެފާނު) ވިދާޅުވިއެވެ. ﷲ ފިޔަވައި އަޅުކަންކުރުމަށް ތިޔަބައިމީހުން ހިފިކަން ކަށަވަރީ ބުދުތަކެކެވެ. އެއީ ދުނިޔޭގެ ހަޔާތުގައި ތިޔަބައިމީހުންގެ މެދުގައި އެކުވެރިކަން ދެމިއޮތުމަށްޓަކައެވެ. ދެން އެއަށްފަހު، ގިޔާމަތް ދުވަހުން ތިޔަބައިމީހުންގެ ތެރެއިން އެއްބަޔަކު، އަނެއްބަޔަކަށް ކާފިރު ވާނެތެވެ. އަދި އެއްބަޔަކު އަނެއްބަޔަކަށް ލައުނަތް ލެއްވުމަށް އެދޭނެތެވެ. އަދި ތިޔަބައިމީހުން ތިބެނިވި ތަނަކީ ނަރަކަޔެވެ. އަދި (އެދުވަހުން) ތިޔަބައިމީހުންނަށް ނަސްރު ދޭނޭ އެއްވެސް ބަޔަކު ނުވެތެވެ.","",""],["","","","فآمن له لوط وقال إني مهاجر إلى ربي إنه هو العزيز الحكيم","ފަހެ، ލޫޠުގެފާނު، އެކަލޭގެފާނުގެ (އެބަހީ: އިބްރާހީމްގެފާނުގެ) ބަސްފުޅު ތެދުކުރެއްވިއެވެ. އަދި އެކަލޭގެފާނު (އެބަހީ: އިބްރާހީމްގެފާނު) ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިމަންގެ ވެރިރަސްކަލާނގެ އެންގެވިފަރާތަށް ތިމަން، ހިޖުރަށް މިދަނީއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ووهبنا له إسحاق ويعقوب وجعلنا في ذريته النبوة والكتاب وآتيناه أجره في الدنيا وإنه في الآخرة لمن الصالحين","އަދި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް (އެބަހީ: އިބްރާހީމްގެފާނަށް) އިސްޙާގުގެފާނު ދެއްވައި އަދި (ކާފަދަރިކަލުން) ޔައުގޫބުގެފާނު ދެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ، އެކަލޭގެފާނުގެ ދަރިކޮޅުގައި ނަބީކަމާއި (ވަހީގެ) ފޮތް ލެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ދުނިޔޭގައި ހެޔޮ ދަރުމަ ދެއްވީމެވެ. އަދި ހަމަކަށަވަރުން، އެކަލޭގެފާނު، އާޚިރަތުގައި ވަނީ ސާލިހުންގެ ތެރެއިންކަން ކަށަވަރެވެ.","",""],["","","","ولوطا إذ قال لقومه إنكم لتأتون الفاحشة ما سبقكم بها من أحد من العالمين","އަދި ލޫޠުގެފާނު، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް ވިދާޅުވިހިނދު (ހަނދުމަކުރާށެވެ!) ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ތިޔަކުރާ ފާޙީޝް ކަންތައްތަކަކީ، އާލަމްތަކުގެ ތެރެއިން އެކަކުވެސް މީގެކުރިން ކޮށްފައިނުވާ ކަންތައްތަކެކެވެ.","",""],["","","","أئنكم لتأتون الرجال وتقطعون السبيل وتأتون في ناديكم المنكر فما كان جواب قومه إلا أن قالوا ائتنا بعذاب الله إن كنت من الصادقين","ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ފިރިހެނުން ގާތަށް (ޝަހްވާނީ އެދުން ފުއްދުމަށް) ދަނީ ހެއްޔެވެ؟ އަދި ތިޔަބައިމީހުން މަގުފޭރި، ތިޔަބައިމީހުންގެ ނާދީތަކުގައި އެ ނުބައިކަންތައް ކުރަމުން ގެންދަނީ ހެއްޔެވެ؟ ފަހެ، އެކަލޭގެފާނުގެ (އެބަހީ: ލޫޠުގެފާނުގެ) ގައުމުގެމީހުންގެ ޖަވާބުކަމުގައި އެއުރެންގެ މި ބުނުން ނޫނީ ނުވެތެވެ. ކަލޭގެފާނު ތެދުވެރިންގެ ތެރެއިންވަނީނަމަ، ތިމަންމެންނަށް (ތިޔަ ވިދާޅުވާ) ﷲގެ އަޒާބު ނިކަންގެނެސްދެއްވައި ބައްލަވާށެވެ!","",""],["","","","قال رب انصرني على القوم المفسدين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ފަސާދަކުރާމީހުންގެ މައްޗަށް މިއަޅާއަށް ނަސްރު ދެއްވާނދޭވެ!","",""],["","","","ولما جاءت رسلنا إبراهيم بالبشرى قالوا إنا مهلكو أهل هذه القرية إن أهلها كانوا ظالمين","އުފާވެރިކަމުގެ ޚަބަރާއިގެން ތިމަންރަސްކަލާނގެ ފޮނުއްވި މަލާއިކަތުން އިބްރާހީމްގެފާނުގެ އަރިހަށް ވަޑައިގަތްހިނދު، އެބޭކަލުން ވިދާޅުވޫއެވެ. ހަމަކަށަވަރުން، ތިމަންމެން ފޮނުއްވެވީ މިރަށުގެ (އެބަހީ: ލޫޠުގެފާނުގެ ރަށުގެ) އަހުލުވެރިން ހަލާކު ކުރުމަށެވެ. ހަމަކަށަވަރުން، އެ ރަށުގެ އަހުލުވެރިންވީ އަނިޔާވެރިން ކަމުގައެވެ.","",""],["","","","قال إن فيها لوطا قالوا نحن أعلم بمن فيها لننجينه وأهله إلا امرأته كانت من الغابرين","އެކަލޭގެފާނު (އެބަހީ: އިބްރާހީމްގެފާނު) ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، އެރަށުގައި ލޫޠުގެފާނު އެބަހުންނެވިއެވެ. އެބޭކަލުން ވިދާޅުވޫއެވެ. އެރަށުގައިވާ ބަޔަކު، ތިމަންމެންނަށް މާރަނގަޅަށް އެނގެއެވެ. ހަމަކަށަވަރުން، ތިމަންމެން އެކަލޭގެފާނުގެ އަނބިކަނބަލުން މެނުވީ އެކަލޭގެފާނާއި، އެކަލޭގެފާނުގެ އަހުލުވެރިން ސަލާމަތްކުރާ ހުށީމެވެ. އެކަނބުލޭގެވީ ހަލާކުވެގެންދިޔަ މީހުންގެތެރެއިންނެވެ.","",""],["","","","ولما أن جاءت رسلنا لوطا سيء بهم وضاق بهم ذرعا وقالوا لا تخف ولا تحزن إنا منجوك وأهلك إلا امرأتك كانت من الغابرين","އަދި ތިމަންރަސްކަލާނގެ ރަސޫލުން (އެބަހީ: މަލާއިކަތުން) ލޫޠުގެފާނުގެ އަރިހަށް ވަޑައިގަތް ހިނދު، (ގައުމުގެމީހުންގެ ފާސިދުކަމުގެ ސަބަބުން އެބޭކަލުންނަށް ދެރަގޮތެއް ވެދާނެތީ) އެބޭކަލުންނާމެދު ދެރަފުޅުވެ، ހިތާމަކުރެއްވިއެވެ. އަދި އެބޭކަލުން ދެންނެވޫއެވެ. ބިރުފުޅުގެން ވަޑައިނުގަންނަވާށެވެ! އަދި ހިތާމަވެސް ނުކުރައްވާށެވެ. ހަމަކަށަވަރުން، ތިމަންމެން ކަލޭގެފާނާއި، ކަލޭގެފާނުގެ އަހުލުވެރިން ސަލާމަތް ކުރާނޫއެވެ. ކަލޭގެފާނުގެ އަނބިކަނބަލުން މެނުވީއެވެ. އެކަނބުލޭގެވީ، ހަލާކުވެގެންދިޔަ މީހުންގެ ތެރެއިންނެވެ.","",""],["","","","إنا منزلون على أهل هذه القرية رجزا من السماء بما كانوا يفسقون","(މަލާއިކަތުން ވިދާޅުވޫއެވެ.) ހަމަކަށަވަރުން، ތިމަންމެން މިރަށުގެ އަހުލުވެރިންގެ މައްޗަށް، އެއުރެން ފާސިގު ވުމުގެ ސަބަބުން (ﷲގެ އަމުރު ފުޅަށް) އުޑުން އަޒާބެއް ފޮނުވާހުށީމެވެ.","",""],["","","","ولقد تركنا منها آية بينة لقوم يعقلون","އަދި އެކަމުގެ ތެރެއިން ބަޔާން ވެގެންވާ ހެތްކެއް، ހަމަކަށަވަރުން، ވިސްނާ ބަޔަކަށް، ތިމަންރަސްކަލާނގެ ދޫކުރެއްވީމެވެ.","",""],["","","","وإلى مدين أخاهم شعيبا فقال يا قوم اعبدوا الله وارجوا اليوم الآخر ولا تعثوا في الأرض مفسدين","އަދި މަދްޔަންގެމީހުންގެ ގާތަށް، އެއުރެންގެ އަޚު، ޝުއައިބުގެފާނު ފޮނުއްވީމެވެ. ފަހެ، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން ﷲއަށް އަޅުކަންކުރާށެވެ! އަދި ތިޔަބައިމީހުން އާޚިރަތް ދުވަހަށް އެދޭށެވެ! އަދި ފާސިދު ންކަމުގައިވެ ތިބެ، ތިޔަބައިމީހުން ބިމުގައި ފަސާދަ ނުކުރާހުށި ކަމެވެ!","",""],["","","","فكذبوه فأخذتهم الرجفة فأصبحوا في دارهم جاثمين","ފަހެ، އެއުރެން އެކަލޭގެފާނު (އެބަހީ: ޝުއައިބުގެފާނު) ދޮގުކުޅައޫއެވެ. ދެން ބިރުވެރި ބިންހެލުމެއް އެމީހުންނަށް އައިސްޖެހުނެވެ. އަދި އެއުރެންގެ ގެތަކުގައި ކަކޫމައްޗަށްތިރިވެ، މަރުވެފައިތިބި ބަޔަކުކަމުގައި އެބައިމީހުން ވެއްޖައޫއެވެ.","",""],["","","","وعادا وثمود وقد تبين لكم من مساكنهم وزين لهم الشيطان أعمالهم فصدهم عن السبيل وكانوا مستبصرين","އަދި ތިމަންރަސްކަލާނގެ ޢާދު ބާގައިމީހުންނާއި، ޘަމޫދު ބާގައިމީހުން ހަލާކުކުރެއްވީމެވެ. އެއުރެންގެ ގެތަކުން ތިޔަބައިމީހުންނަށްޓަކައި މިކަމުގެ ހެކިތައް ފާޅުވެ އެނގިގެންވެތެވެ. އަދި ޝައިތާނާ، އެއުރެންނަށް އެއުރެންގެ ޢަމަލުތައް ޒީނަތްތެރިކޮށް ދެއްކިއެވެ. އަދި ތެދުމަގުން އެއުރެން ދުރުކުރިއެވެ. ބުއްދިވެރިންކަމުގައި އެއުރެންވިއަސް މެއެވެ. (ނޯޓު: ނަމަވެސް، އެއުރެންގެ ބުއްދީގެ ބޭނުން ނުކޮށް ހައްގުގެ މަގުން އެއްކިބާވެގަތޫއެވެ.)","",""],["","","","وقارون وفرعون وهامان ولقد جاءهم موسى بالبينات فاستكبروا في الأرض وما كانوا سابقين","އަދި ތިމަންރަސްކަލާނގެ ގާރޫނާއި، ފިރްޢައުނާއި، ހާމާނު ހަލާކުކުރެއްވީމެވެ. އަދި ހަމަކަށަވަރުން، ބަޔާން ވެގެންވާ ހެކިތަކާއިގެން މޫސާގެފާނު، އެއުރެންގެ ގާތަށް ވަޑައިގެންނެވިއެވެ. ފަހެ، އެއުރެން ބިމުގައި ބޮޑާވެގަތޫއެވެ. އަދި (ތިމަންރަސްކަލާނގެ އަޒާބުން) މިންޖުވެގެންދިޔަ ބަޔަކު ކަމުގައި އެއުރެން ނުވޫއެވެ.","",""],["","","","فكلا أخذنا بذنبه فمنهم من أرسلنا عليه حاصبا ومنهم من أخذته الصيحة ومنهم من خسفنا به الأرض ومنهم من أغرقنا وما كان الله ليظلمهم ولكن كانوا أنفسهم يظلمون","އަދި އެއިން ކޮންމެ ބަޔަކުވެސް، އެބަޔެއްގެ ކުށުގެ ސަބަބުން ތިމަންރަސްކަލާނގެ ގެންދެވީމެވެ. ފަހެ، ތަންތަން ހަލާކުކުރަނިވި ގަދަ ވަޔެއް ތިމަންރަސްކަލާނގެ އެބަޔެއްގެ މައްޗަށް ފޮނުއްވި މީހުން އެއުރެންގެ ތެރެއިންވޫއެވެ. އަދި އަޒާބުގެ ގަދައަޑެއް ފޮނުއްވައި ގެންދެވި މީހުންވެސް އެއުރެންގެ ތެރެއިންވޫއެވެ. އަދި އެއުރެންނާއެކު ބިންގަނޑު ގަންބަވައިގަތް މީހުންވެސް އެއުރެންގެ ތެރެއިންވޫއެވެ. އަދި (ކަނޑުލައްވައި) ޣަރަގުކުރެއްވި މީހުންވެސް އެއުރެންގެ ތެރެއިންވޫއެވެ. އެއުރެންނަށް އަނިޔާކުރެއްވުމަކަށް ﷲ އިރާދައެއް ނުކުރައްވަތެވެ. އެހެނެއްކަމަކު، އެއުރެންގެ ނަފްސުތަކަށް ހަމަ އެއުރެން އަނިޔާކުރި ކަމުގައިވިއެވެ.","",""],["","","","مثل الذين اتخذوا من دون الله أولياء كمثل العنكبوت اتخذت بيتا وإن أوهن البيوت لبيت العنكبوت لو كانوا يعلمون","ﷲ ފިޔަވައި، އެހީތެރިންތަކެއް ލިބިގަތް މީހުންގެ މިސާލީ، ގެއެއް ހަދައި ބޭނުންކުޅަ، ފައިދިގުމަކުނުގެ މިސާލެވެ. ހަމަކަށަވަރުން، ގެތަކުގެ ތެރެއިން އެންމެ ދެރަވަރު ގެއަކީ، ފައިދިގުމަކުނުގެ ގެކަން ކަށަވަރެވެ. އެކަން އެއުރެން ދަންނަނަމައެވެ.","",""],["","","","إن الله يعلم ما يدعون من دونه من شيء وهو العزيز الحكيم","ހަމަކަށަވަރުން، ﷲ ފިޔަވައި އެއުރެން އަޅުކަންކޮށް އުޅުނު ތަކެތި އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަދި އެކަލާނގެއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وتلك الأمثال نضربها للناس وما يعقلها إلا العالمون","އަދި އެ މިސާލުތައް ތިމަންރަސްކަލާނގެ މީސްތަކުންނަށް ޖައްސަވަމެވެ. އަދި އިލްމުވެރިންނަށް މެނުވީ، އެ މިސާލުތަކެއް ނުވިސްނޭނެތެވެ.","",""],["","","","خلق الله السماوات والأرض بالحق إن في ذلك لآية للمؤمنين","ﷲ އުޑުތަކާއި، ބިން، ހައްގު ގޮތުގައި ހެއްދެވިއެވެ. ހަމަކަށަވަރުން، މުއުމިނުންނަށް އެކަމުގައި ހެތްކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","اتل ما أوحي إليك من الكتاب وأقم الصلاة إن الصلاة تنهى عن الفحشاء والمنكر ولذكر الله أكبر والله يعلم ما تصنعون","ފޮތުގެ ތެރެއިން ކަލޭގެފާނަށް ވަހީކުރެއްވި ތަކެތި ކިޔަވައި ވިދާޅުވާށެވެ! އަދި ކަލޭގެފާނު ނަމާދު ގާއިމުކުރައްވާށެވެ! ހަމަކަށަވަރުން، ނަމާދަކީ ހުތުރުކަންބޮޑު ފާފަތަކާއި، މުންކަރާތްތައް ނަހީކުރާ ކަމެކެވެ. އަދި ހަމަކަށަވަރުން، ﷲ ހަނދުމަ ކުޅައުމަކީ، އެންމެ ބޮޑު ކަންތަކެވެ. އަދި ތިޔަބައިމީހުން ކުރާ ކަންތައް ﷲ ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","ولا تجادلوا أهل الكتاب إلا بالتي هي أحسن إلا الذين ظلموا منهم وقولوا آمنا بالذي أنزل إلينا وأنزل إليكم وإلهنا وإلهكم واحد ونحن له مسلمون","ރިވެތިވެގެންވާ ގޮތުގައި މެނުވީ ތިޔަބައިމީހުން ފޮތުގެ އަހުލުވެރިންނާ ޖަދަލު ނުކުރާށެވެ! އެއުރެންގެ ތެރެއިން އަނިޔާވެރިވެގެންވާ މީހުން ފިޔަވައި އެހެން މީހުންނަށެވެ. އަދި ތިމަންމެންނަށް ބާވައިލެއްވި ފޮތަށާއި، ތިޔަބައިމީހުންނަށް ބާވައިލެއްވި ފޮތަށް ތިމަންމެން އީމާން ވެއްޖައީމޭ ތިޔަބައިމީހުން ބުނާށެވެ! ތިމަންމެންގެ އިލާހަކީވެސް، އަދި ތިޔަބައިމީހުންގެ އިލާހަކީވެސް އެއް އިލާހެކެވެ. އަދި ތިމަންމެން އެކަލާނގެއަށް ކިޔަމަންވެ، އިސްލާމް ވަމުއެވެ.","",""],["","","","وكذلك أنزلنا إليك الكتاب فالذين آتيناهم الكتاب يؤمنون به ومن هؤلاء من يؤمن به وما يجحد بآياتنا إلا الكافرون","ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ފޮތް ބާވައިލެއްވީ އެފަދައިންނެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ ފޮތް ދެއްވި މީހުންގެ ތެރެއިން ބަޔަކު އެ ފޮތަށް އީމާން ވެތެވެ. އަދި މިބައިމީހުންގެ ތެރެއިން (އެބަހީ: މައްކާގެ އަހުލުވެރިންގެ ތެރެއިން) އެ ގުރްއާނަށް އީމާންވާ ބަޔަކުވެސްވެއެވެ. އަދި ކާފިރުން މެނުވީ، ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާމެދު ދެކޮޅެއް ނަހަދާނެތެވެ.","",""],["","","","وما كنت تتلو من قبله من كتاب ولا تخطه بيمينك إذا لارتاب المبطلون","އަދި އޭގެކުރިން ކަލޭގެފާނު އެއްވެސް ފޮތެއް ކިޔަވައިވިދާޅުވެއެއް ނޫޅުއްވަމުއެވެ. އަދި ކަލޭގެފާނުގެ އަތްޕުޅުން އެއްވެސް ފޮތެއް ނުލިޔުއްވަމުއެވެ. އެކަން އެހެންވީނަމަ، ކާފިރުން ޝައްކުކުރީހެވެ.","",""],["","","","بل هو آيات بينات في صدور الذين أوتوا العلم وما يجحد بآياتنا إلا الظالمون","އަދި ކިއެއްތަ! އެއީ އިލްމު ލިބިގެންވާ މީހުންގެ ހިތްތަކުގައި ބަޔާން ވެގެންވާ އާޔަތް ތަކެކެވެ. އަނިޔާވެރިން ނޫނީ، ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާ ދެކޮޅެއް ނަހަދާނެތެވެ.","",""],["","","","وقالوا لولا أنزل عليه آيات من ربه قل إنما الآيات عند الله وإنما أنا نذير مبين","އެއުރެން ބުނޫއެވެ. އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން މުއުޖުޒާތް ތަކެއް އެކަލޭގެފާނަށް ބާވައިނުލެއްވީ ކީއްވެގެން ހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! މުއުޖުޒާތްތައް ބާވައިލައްވާކަން ކަށަވަރީ، ﷲގެ ހަޒުރަތުންނެވެ. އަދި ތިމަންކަލޭގެފާނު ވާކަން ކަށަވަރީ، ބަޔާން ވެގެންހުރި، އިންޒާރުކުރައްވާ ބޭކަލަކު ކަމުގައެވެ.","",""],["","","","أولم يكفهم أنا أنزلنا عليك الكتاب يتلى عليهم إن في ذلك لرحمة وذكرى لقوم يؤمنون","ހަމަކަވަރުން، އެއުރެންނަށް ކިޔަވައިދެވޭ ފޮތް، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ބާވައިލެއްވިކަން (މުއުޖިޒާއެއް ކަމުގައި) އެއުރެންނަށް ނުފުދެނީ ހެއްޔެވެ؟ ހަމަކަށަވަރުން، އީމާންވާ ބަޔަކަށް އެކަމުގައި ރަހުމަތާއި، ހަނދުމަކުރުމެއް ވާކަން ކަށަވަރެވެ.","",""],["","","","قل كفى بالله بيني وبينكم شهيدا يعلم ما في السماوات والأرض والذين آمنوا بالباطل وكفروا بالله أولئك هم الخاسرون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނާއި، ތިޔަބައިމީހުންނާ ދެމެދު ހެތްކެއް ކަމަށް ﷲ ފުދެއެވެ. އުޑުތަކާއި، ބިމުގައިވާހާ ތަކެތި އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. ބާތިލު ކަންތަކަށް އީމާންވެ، އަދި ﷲއަށް ކާފިރު ވެގެންވާ މީހުން (ދަންނާށެވެ!) ގެއްލެނިވެގެންވާ މީހުންނަކީ ހަމަ އެއުރެންނެވެ.","",""],["","","","ويستعجلونك بالعذاب ولولا أجل مسمى لجاءهم العذاب وليأتينهم بغتة وهم لا يشعرون","އަޒާބު އަވަސްވުމަށް ކަލޭގެފާނުގެ އަރިހުން އެއުރެން އެދޭނެތެވެ. ކަނޑައެޅިގެންވާ މުއްދަތެއް ނެތްނަމަ، އަޒާބެއުރެންނާ ހަމަޔަށް އަތުވެއްޖައީސްކަން ކަށަވަރެވެ. އަދި އެއުރެން ނުދެނެތިއްބައި، ކުއްލިއަކަށް އެއުރެންނާ ހަމަޔަށް އެކަން އަންނާނެކަން ކަށަވަރެވެ.","",""],["","","","يستعجلونك بالعذاب وإن جهنم لمحيطة بالكافرين","އަޒާބު އަވަސްވުމަށް ކަލޭގެފާނުގެ އަރިހުން އެއުރެން އެދޭނެތެވެ. ހަމަކަށަވަރުން، ނަރަކަވަނީ ކާފިރުން ވަށައިލާފައިކަން ކަށަވަރެވެ.","",""],["","","","يوم يغشاهم العذاب من فوقهم ومن تحت أرجلهم ويقول ذوقوا ما كنتم تعملون","އެއުރެންގެ މަތިންނާއި، އެއުރެންގެ ފައިދަށުން އަޒާބު އައިސްޖެހޭ ދުވަހެވެ. އަދި އެދުވަހުން އެކަލާނގެ އަންގަވާނެތެވެ. ތިޔަބައިމީހުން ކޮށްއުޅުނު ޢަމަލުތަކުގެ ރަހަ ތިޔަބައިމީހުން ލިބިގަންނާށެވެ!","",""],["","","","يا عبادي الذين آمنوا إن أرضي واسعة فإياي فاعبدون","އޭ (ތިމަންރަސްކަލާނގެއަށް) އީމާންވި، ތިމަންރަސްކަލާނގެ އަޅުތަކުންނޭވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ބިން (ތިޔަބައިމީހުން ހިޖުރަކުރުމަށްޓަކައި) ތަނަވަސްވެގެންވެތެވެ. ފަހެ، ހަމައެކަނި ތިމަންރަސްކަލާނގެއަށް ތިޔަބައިމީހުން އަޅުކަން ކުރާހުށިކަމެވެ!","",""],["","","","كل نفس ذائقة الموت ثم إلينا ترجعون","ކޮންމެ ނަފްސަކީވެސް، މަރުގެ ރަހަ ލިބިގަންނާނޭ އެއްޗެކެވެ. ދެން ތިޔަބައިމީހުން އެނބުރި ރުޖޫއަކުރައްވާހުށީ، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","والذين آمنوا وعملوا الصالحات لنبوئنهم من الجنة غرفا تجري من تحتها الأنهار خالدين فيها نعم أجر العاملين","އަދި އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަމީހުން (ދަންނާށެވެ!) އެތަންތާނގެ ދަށުން ކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކުގެ އެންމެމަތީ ދަރަޖަތަކަށް ތިމަންރަސްކަލާނގެ އެއުރެން ލައްވާހުށީމެވެ. އެއުރެން އެތަންތާނގައި ދެމިތިބޭ ގޮތުގައެވެ. ހެޔޮ ޢަމަލުކުޅަ މީހުންނަށްހުރި ދަރުމައިގެ މޮޅުކަމާއެވެ!","",""],["","","","الذين صبروا وعلى ربهم يتوكلون","އެއުރެންނީ ކެތްތެރިވި މީހުންނެވެ. އަދި އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ވަކީލުކުރާމީހުންނެވެ.","",""],["","","","وكأين من دابة لا تحمل رزقها الله يرزقها وإياكم وهو السميع العليم","ދިރޭތަކެތީގެ ތެރެއިން އެ އެއްޗެއްގެ ރިޒްގު ލިބިގަތުމަށް ކުޅަދާނަވެގެންވާ ކިތައް ކިތައްއެތި ވޭހެއްޔެވެ؟ އެ ތަކެއްޗަށާއި، ތިޔަބައިމީހުންނަށް ރިޒްގު ދެއްވަނީ ﷲއެވެ. އެކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ولئن سألتهم من خلق السماوات والأرض وسخر الشمس والقمر ليقولن الله فأنى يؤفكون","ހަމަކަށަވަރުން، އުޑުތަކާއި، ބިން ހައްދަވައި، އިރާއި، ހަނދު ޚިދުމަތް ތެރިކުރެއްވީ ކާކުހޭ، އެއުރެން ކުރެން (އެބަހީ: މުޝްރިކުން ކުރެން) ކަލޭގެފާނު އައްސަވައިފިނަމަ، އެއުރެން ﷲ އޭ ދަންނަވާނެކަން ކަށަވަރެވެ. ފަހެ، އެއުރެން ހައްގުން އެއްކިބާވަނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","الله يبسط الرزق لمن يشاء من عباده ويقدر له إن الله بكل شيء عليم","ﷲ، އެކަލާނގެ އަޅުތަކުންގެ ތެރެއިން އިރާދަކުރައްވާ އަޅަކަށް ރިޒްގު ތަނަވަސްކޮށްދެއްވަތެވެ. އަދި އެކަލާނގެ (އިރާދަކުރައްވާ) އަޅަކަށް (ރިޒްގު) ދަތިކުރައްވަތެވެ. ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެ ކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ولئن سألتهم من نزل من السماء ماء فأحيا به الأرض من بعد موتها ليقولن الله قل الحمد لله بل أكثرهم لا يعقلون","އަދި ހަމަކަށަވަރުން، އުޑުން ފެންބާވައިލައްވައި، ބިން މަރުވެފައި އޮތުމަށްފަހު، އެ ފެނުން ބިމަށް ދިރުން ދެއްވީ ކާކުހޭ އެއުރެން ކުރެން ކަލޭގެފާނު އައްސަވައިފިނަމަ، ހަމަކަށަވަރުން، އެއުރެން ﷲ އޭ ދަންނަވާނެކަން ކަށަވަރެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމްދު ހުރީ ﷲއަށެވެ. އަދި ކިއެއްތަ! އޭގެތެރެއިން ގިނަމީހުންނަކަށް (އެކަމެއް) ނުވިސްނެތެވެ.","",""],["","","","وما هذه الحياة الدنيا إلا لهو ولعب وإن الدار الآخرة لهي الحيوان لو كانوا يعلمون","މިދުނިޔޭގެ ދިރިއުޅުމަކީ، ކުޅިވަރެއް ކަމުގައްޔާއި، މަޖަލެއް ކަމުގައި ނޫނީ ނުވެތެވެ. އަދި ހަމަކަށަވަރުން، ހަގީގީ ދިރިއުޅުންވަނީ، އާޚިރަތްގެ ގޮވަތީގައިކަން ކަށަވަރެވެ. އެއުރެންނަށް އެކަން އެނގޭނަމައެވެ.","",""],["","","","فإذا ركبوا في الفلك دعوا الله مخلصين له الدين فلما نجاهم إلى البر إذا هم يشركون","ފަހެ، އެއުރެން ނަވަށް އެރިހިނދު، އެކަލާނގެއަށް އީމާން ކަން ޚާލިސްކުރާ ޙާލުގައި، ﷲއަށް އެއުރެން ދުއާކުރެތެވެ. ފަހެ އެކަލާނގެ އެއުރެން ސަލާމަތް ކުރައްވައި، އެއްގަމަށް ގެންނެވިހިނދު، އެއުރެން (އެކަލާނގެއަށް) ޝަރީކުކުރެތެވެ.","",""],["","","","ليكفروا بما آتيناهم وليتمتعوا فسوف يعلمون","(އެއުރެން ޝަރީކުކުރަނީ) އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ދެއްވި ނިއުމަތަށް ކާފިރު ވުމަށްޓަކައެވެ. އަދި އެއުރެން (ދުނިޔޭގައި) ވަގުތުކޮޅަކަށް އަރާމު ލިބިގަތުމަށްޓަކައެވެ. ފަހެ، ނިކަންހުރެ، އެއުރެންނަށް (އޭގެ ނަތީޖާ) އެނގޭހުއްޓެވެ.","",""],["","","","أولم يروا أنا جعلنا حرما آمنا ويتخطف الناس من حولهم أفبالباطل يؤمنون وبنعمة الله يكفرون","ހަމަކަށަވަރުން، އަމާން ކަން ލިބިގެންވާ ހަރަމް ފުޅެއް ތިމަންރަސްކަލާނގެ ލެއްވިކަން އެއުރެންނަށް ނޭނގެނީ ހެއްޔެވެ؟ އެއީ އެއުރެންގެ ވަށައިގެން އެކަކު އަނެކަކު މަރައި އަޅުވެތިކޮށް އުޅުނުތަނެވެ. (މިކަން މިހެން އޮތުމާއެކުވެސް) އެއުރެން ބާތިލަށް އީމާންވެ، ﷲގެ ނިއުމަތަށް ކާފިރު ވަނީ ހެއްޔެވެ؟","",""],["","","","ومن أظلم ممن افترى على الله كذبا أو كذب بالحق لما جاءه أليس في جهنم مثوى للكافرين","ﷲއާމެދު ހަދައިގެން ދޮގުބުނި މީހަކަށްވުރެން، ނުވަތަ އެކަލާނގެ ހައްގު ބަސްފުޅު އޭނާގެ ގާތަށް އައިހިނދު، އެ ބަސްފުޅު ދޮގުކުޅަ މީހަކަށްވުރެން އަނިޔާވެރިކަން ބޮޑީ ކާކުހެއްޔެވެ؟ ކާފިރުން ތިބޭނެ ތަނެއް ނަރަކައިގައި ނުވޭހެއްޔެވެ؟","",""],["","","","والذين جاهدوا فينا لنهدينهم سبلنا وإن الله لمع المحسنين","ތިމަންރަސްކަލާނގެ މަގުގައި ޖިހާދުކުރި މީހުން (ދަންނާށެވެ!) ހަމަކަށަވަރުން، އެއުރެންނަށް ތިމަންރަސްކަލާނގެ މަގުތަކަށް މަގު ދައްކަވާހުށީމެވެ. އަދި ހަމަކަށަވަރުން، ﷲ ވޮޑިގެންވަނީ، އިހްސާން ތެރިންނާ އެކުގައިކަން ކަށަވަރެވެ.","",""],["","","","بسم الله الرحمن الرحيم الم","ا ل م (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","غلبت الروم","(އަރަބީންނާ) އެންމެ ކައިރި ބިމުގައި (ފާރިސީންގެ އަތުން) ރޫމީން ބަލިވެއްޖައޫއެވެ. އަދި އެއުރެން ބަލިވުމުގެ ފަހަށް، މަދު އަހަރުކޮޅެއްގެ ތެރޭގައި ކާމިޔާބު ހޯދާނެތެވެ. (އެބަހީ: ފާރިސީންގެ މައްޗަށެވެ.) އޭގެކުރިންވެސް އަދި އޭގެފަހުންވެސް ހުރިހާކަމެއް މިލްކުވެގެންވަނީ، ﷲއަށެވެ. އަދި އެދުވަހުން މުއުމިނުން އުފާކުރާނެތެވެ.","",""],["","","","في أدنى الأرض وهم من بعد غلبهم سيغلبون","(އަރަބީންނާ) އެންމެ ކައިރި ބިމުގައި (ފާރިސީންގެ އަތުން) ރޫމީން ބަލިވެއްޖައޫއެވެ. އަދި އެއުރެން ބަލިވުމުގެ ފަހަށް، މަދު އަހަރުކޮޅެއްގެ ތެރޭގައި ކާމިޔާބު ހޯދާނެތެވެ. (އެބަހީ: ފާރިސީންގެ މައްޗަށެވެ.) އޭގެކުރިންވެސް އަދި އޭގެފަހުންވެސް ހުރިހާކަމެއް މިލްކުވެގެންވަނީ، ﷲއަށެވެ. އަދި އެދުވަހުން މުއުމިނުން އުފާކުރާނެތެވެ.","",""],["","","","في بضع سنين لله الأمر من قبل ومن بعد ويومئذ يفرح المؤمنون","(އަރަބީންނާ) އެންމެ ކައިރި ބިމުގައި (ފާރިސީންގެ އަތުން) ރޫމީން ބަލިވެއްޖައޫއެވެ. އަދި އެއުރެން ބަލިވުމުގެ ފަހަށް، މަދު އަހަރުކޮޅެއްގެ ތެރޭގައި ކާމިޔާބު ހޯދާނެތެވެ. (އެބަހީ: ފާރިސީންގެ މައްޗަށެވެ.) އޭގެކުރިންވެސް އަދި އޭގެފަހުންވެސް ހުރިހާކަމެއް މިލްކުވެގެންވަނީ، ﷲއަށެވެ. އަދި އެދުވަހުން މުއުމިނުން އުފާކުރާނެތެވެ.","",""],["","","","بنصر الله ينصر من يشاء وهو العزيز الرحيم","(އެއީ) ﷲގެ ނަސްރުންނެވެ. އެކަލާނގެ އިރާދަކުރައްވާ ބަޔަކަށް ނަސްރު ދެއްވަތެވެ. އަދި އެކަލާނގެއީ، ޢަޒީޒުވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وعد الله لا يخلف الله وعده ولكن أكثر الناس لا يعلمون","ﷲގެ ވައުދު ފުޅެވެ. ﷲ، އެކަލާނގެ ވައުދާ ޚިލާފުވެ ވޮޑިއެއް ނުގަންނަވަތެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުން (އެކަމެއް) ނުދަނެތެވެ.","",""],["","","","يعلمون ظاهرا من الحياة الدنيا وهم عن الآخرة هم غافلون","ދުނިޔޭގެ ދިރިއުޅުމުން އެއުރެންނަށް އެނގެނީ ބޭރުފުށުގެ ކަންތަކެވެ. އަދި އެއުރެންވަނީ، އާޚިރަތް ދުވަހާމެދު ޣާފިލު ވެގެންވާ ބަޔަކު ކަމުގައެވެ.","",""],["","","","أولم يتفكروا في أنفسهم ما خلق الله السماوات والأرض وما بينهما إلا بالحق وأجل مسمى وإن كثيرا من الناس بلقاء ربهم لكافرون","އަދި އެއުރެން، އެއުރެންގެ އަމިއްލަ ނަފްސު ތަކާމެދު ފިކުރެއް ނުކުރޭހެއްޔެވެ؟ ހައްގު ގޮތުގައި، އަދި ކަނޑައެޅިގެންވާ އަޖަލަކަށް މެނުވީ އުޑުތަކާއި، ބިމާއި، އެދެމެދުގައިވާހާ ތަކެއްޗެއް ﷲ ނަހައްދަވަތެވެ. އަދި ހަމަކަށަވަރުން، މީސްތަކުންގެ ތެރެއިން ގިނަމީހުން، އެއުރެންގެ ވެރިރަސްކަލާނގެއާ ބައްދަލުވާނޭކަމަށްވަނީ ކާފިރު ވެގެންކަން ކަށަވަރެވެ.","",""],["","","","أولم يسيروا في الأرض فينظروا كيف كان عاقبة الذين من قبلهم كانوا أشد منهم قوة وأثاروا الأرض وعمروها أكثر مما عمروها وجاءتهم رسلهم بالبينات فما كان الله ليظلمهم ولكن كانوا أنفسهم يظلمون","އަދި ބިމުގައި ދަތުރުފަތުރުކޮށް، އެއުރެންގެ ކުރިން އުޅުނު މީހުންގެ ނިމުންވީ ކޮންފަދައަކުންކަން ފަހެ، އެއުރެން ނުބަލަނީހެއްޔެވެ؟ އެއުރެންނަށްވުރެ ބާރުގަދަ ބަޔަކު ކަމުގައި، އެއުރެން (އެބަހީ: ކުރިން އުޅުނު މީހުން) ވިއެވެ. އަދި އެއުރެން ބިންގަނޑު (ދަނޑުގޮވާން ކުރުމަށާއި، މަޢުދަނުތައް ނެރުމަށް) ތައްޔާރުކުރޫއެވެ. އަދި (މައްކާގެ މުޝްރިކުން) އެ ބިން އާބާދުކުރި ވަރަށްވުރެ ބޮޑަށް، އެއުރެން އެ ބިން އާބާދުކުރޫއެވެ. އަދި އެއުރެންގެ ރަސޫލުން، ފާޅުވެގެންވާ މުއުޖުޒާތް ތަކާއިގެން، އެއުރެންގެ ގާތަށް ވަޑައިގަތެވެ. ފަހެ، ﷲ، އެއުރެންނަށް އަނިޔާކުރައްވާ ކަމުގައެއް ނުވެތެވެ. އެހެނެއްކަމަކު، އެއުރެން، އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް އަނިޔާކުރާކަމުގައި ވިއެވެ.","",""],["","","","ثم كان عاقبة الذين أساءوا السوأى أن كذبوا بآيات الله وكانوا بها يستهزئون","ދެން ނުބައިކޮށް ކަންތައްކުރި މީހުންގެ ނިމުންވީ (އެއުރެންނަށް ލިބުނު) އެންމެ ނުބައި ޖަޒާއަށެވެ. އެއީ އެއުރެން ﷲގެ އާޔަތްތައް ދޮގުކޮށް، އެ އާޔަތްތަކަށް ފުރައްސާރަކޮށް އުޅުނު ބަޔަކު ކަމުގައިވީތީއެވެ.","",""],["","","","الله يبدأ الخلق ثم يعيده ثم إليه ترجعون","(ނެތުމުގެތެރެއިން) ޚަލްގު ތަކުން އަލަށް އުފައްދަވައި، ދެން އަލުން އެ އިއާދަކުރައްވަނީ ﷲއެވެ. ދެން ތިޔަބައިމީހުން ރުޖޫއަކުރައްވާހުށީ އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","ويوم تقوم الساعة يبلس المجرمون","އަދި ގިޔާމަތް ދުވަސް އަންނަހިނދު، ކުށްވެރިންގެ އުންމީދު ކެނޑިދެއެވެ.","",""],["","","","ولم يكن لهم من شركائهم شفعاء وكانوا بشركائهم كافرين","(ﷲ ފިޔަވައި) އެއުރެން އަޅުކަންކޮށް ޝަރީކު ކޮށް އުޅުނު އެއްވެސް ފަރާތެއް އެއީ، އެއުރެންނާމެދު ޝަފާއަތް ތެރިވާ ބަޔަކު ކަމުގައި ނުވިއެވެ. އަދި އެއުރެން އަޅުކަންކޮށް ޝަރީކު ކޮށް އުޅުނު ފަރާތްތަކުގެ ސަބަބުން އެއުރެންވީ ކާފިރުން ކަމުގައެވެ.","",""],["","","","ويوم تقوم الساعة يومئذ يتفرقون","ގިޔާމަތްވާ ދުވަހު އެއުރެން (އެބަހީ: މީސްތަކުން) އެދުވަހުން ދެބަޔަކަށް ބައިވެގެން ދާނެތެވެ.","",""],["","","","فأما الذين آمنوا وعملوا الصالحات فهم في روضة يحبرون","ފަހެ، އީމާންވެ، ސާލިހު ޢަމަލުތައް ކުޅަމީހުން ދަންނާށެވެ! ފަހެ، އެއުރެންވާހުށީ، އުފާވެ، ނިއުމަތް ލިބޭ ޙާލު، (ސުވަރުގޭގެ) ބަގީޗާއެއްގައެވެ.","",""],["","","","وأما الذين كفروا وكذبوا بآياتنا ولقاء الآخرة فأولئك في العذاب محضرون","އަދި ކާފިރުވެ ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާއި، އާޚިރަތާ ބައްދަލުވާނޭކަން ދޮގުކުޅަ މީހުން ދަންނާށެވެ! ފަހެ، އެއުރެންވާހުށީ އަޒާބުގެ ތެރެޔަށް ޙާޒިރުުކުރައްވާފައެވެ.","",""],["","","","فسبحان الله حين تمسون وحين تصبحون","ފަހެ، ތިޔަބައިމީހުން ރޭގަނޑުގެ ތެރެޔަށް ވަންނަހިނދުގައްޔާއި، ފަތިހުގެ ތެރެޔަށް ތިޔަބައިމީހުން ވަންނަހިނދު، ﷲއަށް ތަސްބީހަ ކިޔައި ނަމާދުކުރާށެވެ!","",""],["","","","وله الحمد في السماوات والأرض وعشيا وحين تظهرون","އުޑުތަކާއި، ބިމުގައި އެންމެހާ ތައުރީފާއި ޘަނާ މިލްކުވެގެންވަނީ އެކަލާނގެއަށެވެ. އަދި އަނދިރިވަމުން އަންނަ ވަގުތުގައްޔާއި، ތިޔަބައިމީހުން މެންދުރުގެ ތެރެއަށް ވަންނަހިނދުގައި (ﷲއަށް ތިޔަބައިމީހުން ތަސްބީހަ ކިޔައި ނަމާދުކުރާށެވެ!)","",""],["","","","يخرج الحي من الميت ويخرج الميت من الحي ويحيي الأرض بعد موتها وكذلك تخرجون","މަރުވެފައިވާ ތަކެތިން ދިރޭ ތަކެތި އެކަލާނގެ ނެރުއްވަތެވެ. އަދި ދިރޭ ތަކެތިން މަރުވެފައިވާ ތަކެތި ނެރުއްވަތެވެ. އަދި ބިން މަރުވެ އޮތުމަށްފަހު އެ ބިން ދިރުއްވަތެވެ. އަދި ތިޔަބައިމީހުން (ގިޔާމަތް ދުވަހުން) ނެރުއްވާހުށީވެސް ހަމައެފަދައިންނެވެ.","",""],["","","","ومن آياته أن خلقكم من تراب ثم إذا أنتم بشر تنتشرون","އަދި އެކަލާނގެ ތިޔަބައިމީހުން ވެލީން އުފެއްދެވުންވަނީ، އެކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެކިތަކުގެ ތެރެއިންނެވެ. ދެން އެހިނދު، ތިޔަބައިމީހުން އިންސާނުންގެ ގޮތުގައި (ބިމުގައި) ފެތުރިގެންވަމުއެވެ.","",""],["","","","ومن آياته أن خلق لكم من أنفسكم أزواجا لتسكنوا إليها وجعل بينكم مودة ورحمة إن في ذلك لآيات لقوم يتفكرون","ތިޔަބައިމީހުންނަށްޓަކައި ހަމަތިޔަބައިމީހުންގެ ނަފްސު ތަކުން އަނބިން ހެއްދެވިކަމީ، އެކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެކިތަކުގެ ތެރެއިންވާ ކަމެކެވެ. އެއީ ތިޔަބައިމީހުން އެކަނބަލުންގެ ފަރާތުން ހަމަހިމޭންކަން ލިބިގަތުމަށްޓަކައެވެ. އަދި އެކަލާނގެ ތިޔަބައިމީހުންގެ މެދުގައި ލޯތްބާއި، އޯގާވެރިކަން ލެއްވިއެވެ. ހަމަކަށަވަރުން، ފިކުރު ހިންގާ ބަޔަކަށް އެކަމުގައި ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","ومن آياته خلق السماوات والأرض واختلاف ألسنتكم وألوانكم إن في ذلك لآيات للعالمين","އުޑުތަކާއި ބިން ހެއްދެވުމާއި، ތިޔަބައިމީހުންގެ ދޫތަކާއި (އެބަހީ: ބަސްތަކާއި) ކުލަތައް ތަފާތުވެފައިވާކަމީ، އެކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެކިތަކުގެ ތެރެއިންވާ ކަމެކެވެ. ހަމަކަށަވަރުން، އެކަމުގައި (އެފަދަ ކަންތައް) ދަންނަމީހުންނަށް ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","ومن آياته منامكم بالليل والنهار وابتغاؤكم من فضله إن في ذلك لآيات لقوم يسمعون","އަދި ރޭގަނޑާއި ދުވާލުގެ ވަގުތުގައި ތިޔަބައިމީހުން ނިދާ ނިދުމާއި، އެކަލާނގެ ފަޟްލު ވަންތަކަމުގެ ތެރެއިން އެދި ތިޔަބައިމީހުން މަސައްކަތްކުރުންވަނީ، އެކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެކިތަކުގެ ތެރެއިންނެވެ. ހަމަކަށަވަރުން، އެކަމުގައި އަހާ ބަޔަކަށް ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","ومن آياته يريكم البرق خوفا وطمعا وينزل من السماء ماء فيحيي به الأرض بعد موتها إن في ذلك لآيات لقوم يعقلون","އަދި ތިޔަބައިމީހުންނަށް ބިރުދެއްކެވުމުގެ ގޮތުންނާއި (ވާރެއާމެދު) އެދުންވެރި ކުރެއްވުމުގެ ގޮތުން، ވިދުވަރު ތިޔަބައިމީހުންނަށް ދެއްކެވުމާއި، ބިންގަނޑު މަރުވުމަށްފަހު އުޑުން ފެން ވެއްސަވައި، އެ ފެނުގެ ސަބަބުން އެ ބިން އަލުން ދިރުއްވާކަން ވަނީ، އެކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެކިތަކުގެ ތެރެއިންނެވެ. ހަމަކަށަވަރުން، ވިސްނާބަޔަކަށް އެކަމުގައި ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","ومن آياته أن تقوم السماء والأرض بأمره ثم إذا دعاكم دعوة من الأرض إذا أنتم تخرجون","އަދި އެކަލާނގެ އަމުރު ފުޅަށް، އުޑާއި ބިން ގާއިމުވެ އޮތުންވަނީ، އެކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެކިތަކުގެ ތެރެއިންނެވެ. ދެން ބިމުގެ ތެރެއިން އެކަލާނގެ ތިޔަބައިމީހުންނަށް (ކަށްވަޅުތަކުން ނުކުތުމަށް) ގޮވައިލައްވައިފިނަމަ، އެހިނދު ކުއްލިޔަކަށް ތިޔަބައިމީހުން ނުކުންނާނޫއެވެ.","",""],["","","","وله من في السماوات والأرض كل له قانتون","އަދި އުޑުތަކާއި، ބިމުގައިވާހާ ބަޔަކު މިލްކުވެގެންވަނީ، އެކަލާނގެއަށެވެ. އެ އެންމެން އެކަލާނގެއަށް ކިޔަމަންވެގެންވެތެވެ.","",""],["","","","وهو الذي يبدأ الخلق ثم يعيده وهو أهون عليه وله المثل الأعلى في السماوات والأرض وهو العزيز الحكيم","އަދި އެކަލާނގެއީ (ނެތުމުގެ ތެރެއިން) ޚަލްގު ތަކުން އަލަށް އުފައްދަވައި ދެން އަލުން އެ އިއާދަކުރައްވާ ރަސްކަލާނގެއެވެ. އެކަމަކީ، އެކަލާނގެއަށް ލުއިފަސޭހަ ކަމެކެވެ. އުޑުތަކާއި ބިމުގައި އެންމެ ފުރިހަމަ މިސާލު ވަނީ އެކަލާނގެއަށެވެ. އަދި އެކަލާނގެއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ضرب لكم مثلا من أنفسكم هل لكم من ما ملكت أيمانكم من شركاء في ما رزقناكم فأنتم فيه سواء تخافونهم كخيفتكم أنفسكم كذلك نفصل الآيات لقوم يعقلون","އެކަލާނގެ ތިޔަބައިމީހުންގެ ނަފްސު ތަކުން ތިޔަބައިމީހުންނަށް މިސާލެއް ޖެއްސެވިއެވެ. ތިޔަބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ ދެއްވި ތަކެތީގައި ބައިވެރިވާ ބަޔަކު ތިޔަބައިމީހުންގެ އަޅުންގެ ތެރެއިން ވޭހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުން އެކަމުގައި ހަމަހަމަވެގެންވޭ ހެއްޔެވެ؟ ތިޔަބައިމީހުންގެ އެއްބަޔަކު އަނެއްބަޔަކަށް ބިރުގަންނަ ފަދައިން، އެއުރެންދެކެ ތިޔަބައިމީހުން ބިރުގަންނަމު ހެއްޔެވެ؟ ވިސްނާބަޔަކަށް ތިމަންރަސްކަލާނގެ އާޔަތްތައް ތަފްޞީލު ކޮށްދެއްވަނީ އެފަދައިންނެވެ.","",""],["","","","بل اتبع الذين ظلموا أهواءهم بغير علم فمن يهدي من أضل الله وما لهم من ناصرين","އަދި ކިއެއްތަ! އަނިޔާވެރިވީ މީހުން ނުދަނެތިބެ، އެއުރެންގެ އަމިއްލަ އެދުމަށް ތަބާ ވޫއެވެ. ފަހެ ﷲ މަގުފުރައްދަވައިފި މީހަކަށް ތެދުމަގު ދައްކާނީ ކާކުހެއްޔެވެ؟ އަދި އެއުރެންނަށް ނަސްރު ދޭނޭ އެއްވެސް ބަޔަކު ނުވެތެވެ.","",""],["","","","فأقم وجهك للدين حنيفا فطرت الله التي فطر الناس عليها لا تبديل لخلق الله ذلك الدين القيم ولكن أكثر الناس لا يعلمون","ފަހެ، ބާތިލު މަގުން އެއްކިބާވެ، ހައްގުގެ މަގަށް ތަބާ ވެގެންވާ ޙާލު، ކަލޭގެފާނުގެ މޫނުފުޅު އިސްލާމް ދީނާ ކުރިމަތި ކުރައްވާށެވެ! އެއީ މީސްތަކުން އެ ފިޠުރަތެއްގެ މައްޗަށް އުފެއްދެވި ﷲގެ ފިޠުރަތެވެ. ﷲ އުފެއްދެވި އުފެއްދެވުމަށް ބަދަލެއް ގެނައުމެއް ނެތެވެ. ސީދާވެގެންވާ ދީނަކީ އެއީއެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުން (އެކަމެއް) ނުދަނެތެވެ.","",""],["","","","منيبين إليه واتقوه وأقيموا الصلاة ولا تكونوا من المشركين","އެކަލާނގެއަށް ތިޔަބައިމީހުން ތައުބާވެ، ރުޖޫއަވާ ޙާލު ގައެވެ. އަދި އެކަލާނގެއަށް ތިޔަބައިމީހުން ތަގުވާވެރިވާށެވެ! އަދި ތިޔަބައިމީހުން ނަމާދު ގާއިމުކުރާށެވެ! އަދި މުޝްރިކުންގެ ތެރެއިން ތިޔަބައިމީހުން ނުވާށެވެ!","",""],["","","","من الذين فرقوا دينهم وكانوا شيعا كل حزب بما لديهم فرحون","އެއުރެންގެ ދީން ބައިބައިކޮށް، ބައިތަކެއް ކަމުގައިވީ މީހުންގެ ތެރެއިން (ތިޔަބައިމީހުން ނުވާށެވެ!) ކޮންމެ ބަޔަކުމެ އެއުރެންގެ ގާތުގައިވާ ގޮތާމެދު އުފާކޮށްކޮށް ތިބެތެވެ.","",""],["","","","وإذا مس الناس ضر دعوا ربهم منيبين إليه ثم إذا أذاقهم منه رحمة إذا فريق منهم بربهم يشركون","އަދި މީސްތަކުންނަށް ދަތި ޙާލެއް ޖެހިއްޖެނަމަ، އެއުރެންގެ ވެރި ރަސްކަލާނގެއަށް ތައުބާވެ، ރުޖޫއަވާ ޙާލު، ދުއާކުރެތެވެ. ދެން އެއުރެންނަށް އެކަލާނގެ ހަޒުރަތުން ރަހުމަތެއްގެ ރަހަ ދައްކަވައިފިނަމަ، އެހިނދު އޭގެތެރެއިން ބަޔަކު އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ޝަރީކުކުރެތެވެ.","",""],["","","","ليكفروا بما آتيناهم فتمتعوا فسوف تعلمون","އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ދެއްވި ނިއުމަތަށް ކާފިރު ވުމަށްޓަކައެވެ. ފަހެ، ތިޔަބައިމީހުން (ދުނިޔޭގައި ވަގުތުކޮޅަކަށް) އަރާމު ލިބިގަންނާށެވެ! ފަހެ، ނިކަންހުރެ ތިޔަބައިމީހުންނަށް (އޭގެ ނަތީޖާ) އެނގޭ ހުށްޓެވެ.","",""],["","","","أم أنزلنا عليهم سلطانا فهو يتكلم بما كانوا به يشركون","ނުވަތަ ތިމަންރަސްކަލާނގެއަށް އެއުރެން ޝަރީކުކުރުމަށް ބުނާ ހުއްޖަތެއް ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް ބާވައިލެއްވީ ހެއްޔެވެ؟","",""],["","","","وإذا أذقنا الناس رحمة فرحوا بها وإن تصبهم سيئة بما قدمت أيديهم إذا هم يقنطون","އަދި ތިމަންރަސްކަލާނގެ މީސްތަކުންނަށް ރަހުމަތެއްގެ ރަހަ ދައްކަވައިފިނަމަ، އެއާމެދު އެއުރެން އުފާކުރެތެވެ. އަދި އެއުރެންގެ އަތްތަކުން އިސްކުޅަ ކަންތައްތަކެއްގެ ސަބަބުން، އެއުރެންނަށް ނުބައިކަމެއް ދިމާވެއްޖެނަމަ، އެހިނދު އުންމީދު ކަނޑައިލާ ބަޔަކު ކަމުގައި އެއުރެންވޫއެވެ.","",""],["","","","أولم يروا أن الله يبسط الرزق لمن يشاء ويقدر إن في ذلك لآيات لقوم يؤمنون","ހަމަކަށަވަރުން، ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ރިޒްގު ތަނަވަސް ކުރައްވައި، އަދި (އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ރިޒްގު) ދަތިކުރައްވާކަން އެއުރެން ނުދަންނަނީ ހެއްޔެވެ؟ ހަމަކަށަވަރުން، އީމާންވާ ބަޔަކަށް އެކަމުގައި ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","فآت ذا القربى حقه والمسكين وابن السبيل ذلك خير للذين يريدون وجه الله وأولئك هم المفلحون","ފަހެ، ތިމާގެމީހާއަށާއި، މިސްކީނާ އަށާއި، ދަތުރުވެރިޔާއަށާއި، (މިއިން ކޮންމެ މީހަކަށް) އެމީހެއްގެ ހައްގު ދޭށެވެ! ﷲގެ ވަޖުހުފުޅު އެދިގެން އުޅޭ މީހުންނަށް އެގޮތް ހެޔޮކަން ބޮޑެވެ. އަދި ދިންނަވާނޭ މީހުންނަކީ، ހަމަ އެއުރެންނެވެ.","",""],["","","","وما آتيتم من ربا ليربو في أموال الناس فلا يربو عند الله وما آتيتم من زكاة تريدون وجه الله فأولئك هم المضعفون","އަދި މީސްތަކުންގެ މުދަލުން ރިބާގެ ގޮތުގައި އިތުރުވުމަށްޓަކައި ތިޔަބައިމީހުން ދިން އެއްޗެއް، ﷲގެ ހަޒުރަތުގައި އިތުރުވެގެން ނުދާނެތެވެ. އަދި ﷲގެ ވަޖުހުފުޅު އެދިގެން ޒަކާތްގެ ގޮތުން ތިޔަބައިމީހުން ދިން އެއްޗަކާމެދު (ދަންނާށެވެ!) އިތުރުކުރާ ބަޔަކީ ހަމަ އެއުރެންނެވެ.","",""],["","","","الله الذي خلقكم ثم رزقكم ثم يميتكم ثم يحييكم هل من شركائكم من يفعل من ذلكم من شيء سبحانه وتعالى عما يشركون","ތިޔަބައިމީހުން ހައްދަވައި، ދެން ތިޔަބައިމީހުންނަށް ރިޒްގު ދެއްވައި، ދެން ތިޔަބައިމީހުން މަރުގަންނަވައި، ދެން ތިޔަބައިމީހުން އަލުން ދިރުއްވަނީ ﷲއެވެ. ތިޔަބައިމީހުންގެ ޝަރީކުންގެ ތެރެއިން މިއިން އެއްވެސްކަމެއްކުރާ މީހަކު ވޭހެއްޔެވެ؟ އެއުރެން ޝަރީކުކުރާ ކަންތަކުން އެކަލާނގެ ހުސްތާހިރު ވަންތަވެ، މަތިވެރިވެ ވޮޑިގެންވެއެވެ.","",""],["","","","ظهر الفساد في البر والبحر بما كسبت أيدي الناس ليذيقهم بعض الذي عملوا لعلهم يرجعون","މީސްތަކުންގެ އަތްތަކުން ހޯދައިގަތް ކަންތަކުގެ ސަބަބުން، އެއްގަމާއި ކަނޑުގައި ނުބައިކަން ފާޅުވެއްޖެއެވެ. އެއުރެން ކުރި ބައެއް ޢަމަލުގެ ރަހަ އެއުރެންނަށް ދެއްކެވުމަށެވެ. (އެއީ) އެއުރެން (ތައުބާވެ) ރުޖޫއަ ވުމަށްޓަކައެވެ.","",""],["","","","قل سيروا في الأرض فانظروا كيف كان عاقبة الذين من قبل كان أكثرهم مشركين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ބިމުގައި ދަތުރުފަތުރުކޮށް އުޅޭށެވެ! ދެން ކުރިން އުޅުނު މީހުންގެ ނިމުންއޮތީ ކޮންފަދައަކުންތޯ ތިޔަބައިމީހުން ބަލައި ވިސްނާށެވެ! އޭގެތެރެއިން ގިނަމީހުން މުޝްރިކުން ކަމުގައިވޫއެވެ.","",""],["","","","فأقم وجهك للدين القيم من قبل أن يأتي يوم لا مرد له من الله يومئذ يصدعون","ފަހެ (އެއްވެސް މީހަކަށް) ﷲގެ ހަޒުރަތުން ރައްދުކުރެއްވުމެއްނުވާ ދުވަހެއް އައުމުގެކުރިން، ކަލޭގެފާނުގެ މޫނުފުޅު ސީދާވެގެންވާ ދީނަށް ކުރިމަތިކުރައްވާށެވެ! އެދުވަހުން އެއުރެން (ދެބަޔަކަށް) ބައިވެގެންދާނެތެވެ.","",""],["","","","من كفر فعليه كفره ومن عمل صالحا فلأنفسهم يمهدون","ކާފިރުވި މީހާ (ދަންނާށެވެ!) ފަހެ، އޭނާގެ ކާފިރު ކަން އޮންނާނީ، އޭނާގެ މައްޗަށެވެ. އަދި ސާލިހު ޢަމަލުކުޅަމީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެންގެ ނަފްސު ތަކަށްޓަކައި އެއުރެން މަގު ހޯދައެވެ.","",""],["","","","ليجزي الذين آمنوا وعملوا الصالحات من فضله إنه لا يحب الكافرين","(އެއީ) އީމާންވެ، ސާލިހު ޢަމަލުތައް ކުޅަމީހުންނަށް އެކަލާނގެ ފަޟްލު ވަންތަކަމުން އެއުރެންނަށް ޖަޒާ ދެއްވުމަށްޓަކައެވެ. ހަމަކަށަވަރުން، އެކަލާނގެ، ކާފިރު ންދެކެ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["","","","ومن آياته أن يرسل الرياح مبشرات وليذيقكم من رحمته ولتجري الفلك بأمره ولتبتغوا من فضله ولعلكم تشكرون","އުފާވެރިކަމުގެ ޚަބަރު ދެނިވި ގޮތުގައި، ވައިރޯޅި ފޮނުއްވާކަން އެއީ، އެކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެކިތަކުގެ ތެރެއިންވާ ކަމެކެވެ. (އެއީ) ތިޔަބައިމީހުންނަށް އެކަލާނގެ ރަހުމަތްގެ ރަހަ ދެއްކެވުމަށާއި، އެކަލާނގެ އަމުރު ފުޅަށް އުޅަނދުތައް ދުވުމަށާއި، އެކަލާނގެ ފަޟްލު ވަންތަކަމުން ތިޔަބައިމީހުން އެދިގަތުމަށެވެ. އަދި ތިޔަބައިމީހުން ޝުކުރުވެރިވުމަށްޓަކައެވެ.","",""],["","","","ولقد أرسلنا من قبلك رسلا إلى قومهم فجاءوهم بالبينات فانتقمنا من الذين أجرموا وكان حقا علينا نصر المؤمنين","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ކުރިންވެސް އެބޭކަލުންގެ ގައުމުގެމީހުންގެ ގާތަށް ތިމަންރަސްކަލާނގެ ރަސޫލުން ފޮނުއްވީމެވެ. ފަހެ، އެބޭކަލުން އެއުރެންގެގާތަށް ވަޑައިގަތީ، ފާޅުވެގެންވާ ހެކިތަކާއިގެންނެވެ. ފަހެ (އެބޭކަލުން ދޮގުކޮށް) ފާފަކުރި މީހުންގެ ކިބައިން ތިމަންރަސްކަލާނގެ ބަދަލު ހިއްޕެވީމެވެ. އަދި މުއުމިނުންނަށް ނަސްރު ދެއްވުމަކީ، ތިމަންރަސްކަލާނގެ މައްޗަށްއޮތް ހައްގެއް ކަމުގައިވެއެވެ.","",""],["","","","الله الذي يرسل الرياح فتثير سحابا فيبسطه في السماء كيف يشاء ويجعله كسفا فترى الودق يخرج من خلاله فإذا أصاب به من يشاء من عباده إذا هم يستبشرون","ﷲއީ، ވައިރޯޅިތައް ފޮނުއްވައި، އަދި އެ ވައިރޯޅިތައް ވިލާތައް އުފުލައި، އަދި އެކަލާނގެ އިރާދަކުރައްވާ ފަދައަކުން އުޑުގައި އެ ވިލާތައް ފަތުރުއްވައި، އަދި އެ ވިލާތައް ވަކިވަކިވެގެންދާ އެތިކޮޅުތަކެއް ކަމުގައި ލައްވާ ރަސްކަލާނގެއެވެ. ފަހެ، އެ ވިލާތަކުގެ ތެރެއިން ކެރި ނުކުންނާތީ ތިބާޔަށް ފެންނާނެތެވެ. ފަހެ، އެކަލާނގެ އަޅުތަކުންގެ ތެރެއިން އެކަލާނގެ އިރާދަކުރައްވާ ބަޔަކަށް އޭގެ ނިއުމަތް ދެއްވައިފިނަމަ، އެހިނދު ކުއްލިޔަކަށް އެއުރެން އުފާ ޙާޞިލު ކޮށްގަނެތެވެ.","",""],["","","","وإن كانوا من قبل أن ينزل عليهم من قبله لمبلسين","އަދި އޭގެކުރިން އެއުރެންގެ މައްޗަށް ވާރޭ ވެއްސެވުމުގެކުރިން އުންމީދު ކެނޑި، މާޔޫސްވެފައި ތިބިބަޔަކު ކަމުގައި އެއުރެންވޫއެވެ.","",""],["","","","فانظر إلى آثار رحمت الله كيف يحيي الأرض بعد موتها إن ذلك لمحيي الموتى وهو على كل شيء قدير","ފަހެ، ﷲގެ ރަހުމަތްގެ އަސަރުތައް ދެކެބަލާށެވެ! ބިންގަނޑު މަރުވުމަށްފަހު، (ވާރޭގެ ސަބަބުން) އެކަލާނގެ އެ ބިންގަނޑު ދިރުއްވަނީ ކޮންފަދައަކުން ހެއްޔެވެ؟ ހަމަކަށަވަރުން، އެކަލާނގެއީ، މަރުވެފައިވާ މީހުން ދިރުއްވާ ރަސްކަލާނގެކަން ކަށަވަރެވެ. އެކަލާނގެއީ، ކޮންމެ ކަމަކަށްމެ ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ولئن أرسلنا ريحا فرأوه مصفرا لظلوا من بعده يكفرون","(ﷲ ފޮނުއްވި ރަހުމަތްގެ ސަބަބުން ބިމުންފަޅައި ހެދިގަތް ގަސްތަކުގެ މައްޗަށް) ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ވައިރޯޅިއެއް ފޮނުއްވައި (އޭގެ ސަބަބުން) އެ ގަސްތައް ދޮންވެ، ހިކިގެންދާތަން އެއުރެންނަށް ފެނިއްޖެނަމަ، އޭގެފަހުންވެސް އެއުރެން ކާފިރު ވުމުގައި ދެމިތިބޭކަން ކަށަވަރެވެ.","",""],["","","","فإنك لا تسمع الموتى ولا تسمع الصم الدعاء إذا ولوا مدبرين","ފަހެ، ހަމަކަށަވަރުން، ކަލޭގެފާނަކަށް މަރުވެފައިވާ މީހުންނަށް އަޑެއް ނީއްވެވޭނެތެވެ. އަދި ބީރު މީހުންނަށް އެއުރެން ފުރަގަސްދީ ދާހިނދު، ކަލޭގެފާނު ގޮވައިލައްވާ އަޑެއް ނީއްވެވޭނެތެވެ.","",""],["","","","وما أنت بهاد العمي عن ضلالتهم إن تسمع إلا من يؤمن بآياتنا فهم مسلمون","އަދި ކަނުމީހުންނަށް (އެބަހީ: މަގުފުރެދުމުން ކަނުވެފައިވާ މީހުންނަށް) އެއުރެންގެ މަގުފުރެދުމުން އެއްކިބާ ކުރައްވައި، (ތެދުމަގު ދައްކަވާ) ހާދީއަކު ކަމުގައި ކަލޭގެފާނު ނުވަމުއެވެ. ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް އީމާންވާ ބަޔަކަށް މެނުވީ، ކަލޭގެފާނަކަށް ނީއްވެވޭނެތެވެ. ފަހެ، އެއުރެންނީ، ﷲއަށް ކިޔަމަންވާ މީހުންނެވެ.","",""],["","","","الله الذي خلقكم من ضعف ثم جعل من بعد ضعف قوة ثم جعل من بعد قوة ضعفا وشيبة يخلق ما يشاء وهو العليم القدير","ބަލިކަށިކަމުގެ ތެރެއިން ތިޔަބައިމީހުން ހެއްދެވި ކަލާނގެއީ، ﷲއެވެ. ދެން ބަލިކަށިކަމަށްފަހު، ބާރެއްލައްވައި އަދި ބާރަށްފަހު ބަލިކަށިކަމާއި، ދުވަސްވުމުގެ ދެރަކަމާއި، ނިކަމެތިކަން ލެއްވީވެސް އެކަލާނގެއެވެ. އެކަލާނގެ އިރާދަކުރައްވާ އެއްޗެއް އެކަލާނގެ ހައްދަވަތެވެ. އަދި އެކަލާނގެއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ويوم تقوم الساعة يقسم المجرمون ما لبثوا غير ساعة كذلك كانوا يؤفكون","ގިޔާމަތްގެ ވަގުތުޖެހޭދުވަހު ކުށްވެރިން ހިނދުކޮޅަކަށް މެނުވީ އެއުރެން ނުތިބޭކަމަށް ހުވާކުރާނެތެވެ. (ދުނިޔެމަތީގައި) އެއުރެން ހައްގުން އެއްކިބާވާ ކަމުގައިވީ އެފަދައިންނެވެ.","",""],["","","","وقال الذين أوتوا العلم والإيمان لقد لبثتم في كتاب الله إلى يوم البعث فهذا يوم البعث ولكنكم كنتم لا تعلمون","އަދި އެބަޔަކަށް އިލްމާއި، އީމާން ކަން ލިބިގެންވާ މީހުން ބުނާނެތެވެ. އަލުން ދިރުއްވާނޭ ދުވަހާ ޖެހެންދެން ﷲ ކަނޑައަޅުއްވާފައިވާގޮތަށް ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ތިބެއްޖައީމުއެވެ. ފަހެ، މިއީ އަލުން ދިރުއްވައި ފޮނުއްވާ ދުވަހެވެ. އެހެނެއްކަމަކު ތިޔަބައިމީހުންވީ (އެކަން) ނުދަންނަ ކަމުގައެވެ.","",""],["","","","فيومئذ لا ينفع الذين ظلموا معذرتهم ولا هم يستعتبون","ފަހެ، އެދުވަހުން އަނިޔާވެރިންނަކަށް އެއުރެން ދައްކާ ޢުޛުރަކުން މަންފާއެއް ނުކުރާނެތެވެ. އަދި ހެޔޮމަގަށް އެނބުރި ދިއުމަކަށް، އެއުރެންނަކަށް ތަނެއް ނުމެދެއްވާނޭމެއެވެ.","",""],["","","","ولقد ضربنا للناس في هذا القرآن من كل مثل ولئن جئتهم بآية ليقولن الذين كفروا إن أنتم إلا مبطلون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ މި ގުރްއާންގައި މީސްތަކުންނަށް ހުރިހާ ބާވަތަކުން މިސާލު ޖެއްސެވީމެވެ. އަދި އެއުރެންގެ ގާތަށް މުއުޖިޒާއަކާއިގެން ކަލޭގެފާނު ވަޑައިގެންފިނަމަ، ކާފިރު ވިމީހުން ބުނާނެކަން ކަށަވަރެވެ. ބާތިލުގެ އަހުލުވެރިން ކަމުގައި މެނުވީ ތިޔަބައިމީހުން ނުވަމުއެވެ.","",""],["","","","كذلك يطبع الله على قلوب الذين لا يعلمون","(ﷲގެ އެއްކައުވަންތަކަން) ނުދަންނަ މީހުންގެ ހިތްތަކުގައި، ﷲ ސިއްކަގައްސަވަނީ އެފަދައިންނެވެ.","",""],["","","","فاصبر إن وعد الله حق ولا يستخفنك الذين لا يوقنون","ފަހެ، ކަލޭގެފާނު ކެތްކުރައްވާށެވެ! ހަމަކަށަވަރުން، ﷲގެ ވައުދު ފުޅަކީ ހައްގު ތެދެވެ. އަދި އީމާން ނުވާ މީހުން (ދައްކާ ވާހަކަތަކުން) ކަލޭގެފާނުގެ ކެތްތެރިކަން ކަނޑައިލިޔަ ނުދެއްވާށެވެ!","",""],["","","","بسم الله الرحمن الرحيم الم","ا ل م (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","تلك آيات الكتاب الحكيم","މިއީ ހިކުމަތް ތެރި ފޮތުގެ (އެބަހީ: ގުރްއާންގެ) އާޔަތް ތަކެވެ.","",""],["","","","هدى ورحمة للمحسنين","(އެއީ) އިހްސާން ތެރިންނަށްޓަކައި އޮތް ތެދުމަގާއި، ރަހުމަތެވެ.","",""],["","","","الذين يقيمون الصلاة ويؤتون الزكاة وهم بالآخرة هم يوقنون","އެއުރެންނީ ނަމާދު ގާއިމު ކޮށް، ޒަކާތް ދީ، އަދި އާޚިރަތް ދުވަހާމެދު ޔަގީންކުރާ މީހުންނެވެ.","",""],["","","","أولئك على هدى من ربهم وأولئك هم المفلحون","އެއުރެންވަނީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައި ތެދުމަގެއްގެ މަތީގައެވެ. އަދި ދިންނަވާނޭ މީހުންނަކީ ހަމަ އެއުރެންނެވެ.","",""],["","","","ومن الناس من يشتري لهو الحديث ليضل عن سبيل الله بغير علم ويتخذها هزوا أولئك لهم عذاب مهين","ނުދަނެތިބެ، ﷲގެ މަގުން (މީސްތަކުން) އެއްކިބާކޮށް، އަދި މަލާމާތުގެ ގޮތުގައި ބޭނުންކުރުމަށްޓަކައި ފައިދާއެއްނެތް ވާހަކަ ގަންނަ މީހުންވެސް، މީސްތަކުންގެ ތެރެއިން ވެއެވެ. އިހާނެތިކަންދެނިވި އަޒާބެއުރެންނަށްހުށްޓެވެ.","",""],["","","","وإذا تتلى عليه آياتنا ولى مستكبرا كأن لم يسمعها كأن في أذنيه وقرا فبشره بعذاب أليم","އަދި އެމީހަކަށް ތިމަންރަސްކަލާނގެ އާޔަތްތައް ކިޔަވައިދެވޭހިނދު، ބޮޑާވެގަންނަ ޙާލު (އެއަށް) ފުރަގަސްދީ އެނބުރި ހިނގައިދެއެވެ. އެ އާޔަތްތައް އެމީހަކަށް ނީވޭފަދައެވެ. އެމީހާގެ ދެކަންފަތުގައި ބީރުކަމެއް ހުރިފަދަމެއެވެ. ފަހެ، އެމީހަކަށް ވޭންދެނިވި އަޒާބު ހުރިކަމުގެ ޚަބަރު ކަލޭގެފާނު ދެއްވާށެވެ!","",""],["","","","إن الذين آمنوا وعملوا الصالحات لهم جنات النعيم","ހަމަކަށަވަރުން، އީމާންވެ ސާލިހު ޢަމަލުތައްކުރި މީހުން (ދަންނާށެވެ!) އެއުރެންނަށް ނިއުމަތްގެ ސުވަރުގެތައްހުށްޓެވެ.","",""],["","","","خالدين فيها وعد الله حقا وهو العزيز الحكيم","އެ ސުވަރުގެތަކުގައި ދެމިތިބެނިވި ގޮތުގައެވެ. އެއީ، ﷲގެ ހައްގު ވައުދު ފުޅެވެ. އެކަލާނގެއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","خلق السماوات بغير عمد ترونها وألقى في الأرض رواسي أن تميد بكم وبث فيها من كل دابة وأنزلنا من السماء ماء فأنبتنا فيها من كل زوج كريم","ތިޔަބައިމީހުންނަށް ފެންނަ ތަނބުތަކަކާ ނުލައި، އެކަލާނގެ އުޑުތައް ހެއްދެވިއެވެ. އަދި ތިޔަބައިމީހުންނާއިގެން އެ ބިން ތެޅިފޮޅިގެންފާނެ ކަމަށްޓަކައި، ހަރުލައި ހުންނަ ފަރުބަދަތައް، ބިމުގައި އެކަލާނގެ ލެއްވިއެވެ. އަދި ހިނގާބިނގާ އުޅޭ އެންމެހާ ބާވަތްތަކުގެ ދިރޭ ތަކެތި އެބިމުގައި ފެތުރުއްވިއެވެ. އަދި ތިމަންރަސްކަލާނގެ އުޑުން ފެންވެއްސެވީމެވެ. ދެން އޭގެ ސަބަބުން އެ ބިމުގައި މަންފާ ގިނަ ރަނގަޅު ހުރިހާ ބާވަތަކުން، ގަސްގަހާގެހި ފެޅުއްވީމެވެ.","",""],["","","","هذا خلق الله فأروني ماذا خلق الذين من دونه بل الظالمون في ضلال مبين","މިއީ ﷲގެ ހެއްދެވުމެވެ. އެކަލާނގެ ރަސްކަންފުޅުނޫން ފަރާތްތަކުން ހަދާފައިވަނީ ކޮންއެއްޗެއްކަން، ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނަށް، ފަހެ، ދައްކައިބަލާށެވެ! އަދި ކިއެއްތަ! މުޝްރިކު ންވަނީ ބަޔާންވެގެންވާ މަގުފުރެދުމެއްގެ ތެރޭގައެވެ.","",""],["","","","ولقد آتينا لقمان الحكمة أن اشكر لله ومن يشكر فإنما يشكر لنفسه ومن كفر فإن الله غني حميد","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ލުގުމާނުގެފާނަށް ހިކުމަތް ދެއްވީމެވެ. އަދި ﷲއަށް ޝުކުރުކުރުމަށް އެންގެވީމެވެ. އަދި ޝުކުރުކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާ ޝުކުރުކުރާކަން ކަށަވަރީ، އޭނާގެ އަމިއްލަ ނަފްސަށްޓަކައެވެ. އަދި ކާފިރު ވިމީހާ (ދަންނާށެވެ!) ހަމަކަށަވަރުން، ﷲއީ، ފުދިވޮޑިގެންވާ، ހަމްދު ލިބިވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وإذ قال لقمان لابنه وهو يعظه يا بني لا تشرك بالله إن الشرك لظلم عظيم","އަދި ލުގުމާނުގެފާނު އެކަލޭގެފާނުގެ ދަރިކަލުންނަށް ނަސޭހަތް ދެއްވަމުން ވިދާޅުވިހިނދު ހަނދުމަކުރާށެވެ! އޭ ދަރިފުޅާއެވެ! ﷲއަށް ތިބާ ޝަރީކު ނުކުރާށެވެ! ހަމަކަށަވަރުން، ޝަރީކުކުރުމަކީ ބޮޑުވެގެންވާ އަނިޔާއެކެވެ.","",""],["","","","ووصينا الإنسان بوالديه حملته أمه وهنا على وهن وفصاله في عامين أن اشكر لي ولوالديك إلي المصير","އިންސާނާއަށް، އޭނާގެ މައިންބަފައިންނަށް (ހެޔޮކޮށް ހިތުމަށް) ތިމަންރަސްކަލާނގެ ވަސިއްޔަތްކުރެއްވީމެވެ. އޭނާގެ މައިމީހާ ބަލި ނިކަމެތިކަމުގެ މައްޗަށް، ބަލި ނިކަމެތި ކަމާއެކު މާބަނޑުގައި އޭނާ އުފުލިއެވެ. އަދި އޭނާ ކިރު ތުނބުން ވީއްލުންވަނީ، ދެއަހަރުގައެވެ. (ތިމަންރަސްކަލާނގެ އަމުރުކުރެއްވީމެވެ.) ތިމަންރަސްކަލާނގެއަށާއި، ތިބާގެ މައިންބަފައިންނަށް ޝުކުރުކުރާށެވެ! އެނބުރި ރުޖޫއަ ވުން ވަނީ، ހަމަ ތިމަންރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","وإن جاهداك على أن تشرك بي ما ليس لك به علم فلا تطعهما وصاحبهما في الدنيا معروفا واتبع سبيل من أناب إلي ثم إلي مرجعكم فأنبئكم بما كنتم تعملون","އަދި ތިމަންރަސްކަލާނގެއާމެދު، ތިބާއަށް އެނގުމެއްނުވާ އެއްޗެއް ޝަރީކުކުރުމަށް، އެ ދެމީހުން ގަދައަޅައިފިނަމަ، ފަހެ، ތިބާ އެ ދެމީހުންނަށް ކިޔަމަންނުވާށެވެ! އަދި ދުނިޔޭގައި ހެޔޮގޮތުގައި އެ ދެމީހުންނާއެކު އުޅޭށެވެ! އަދި ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ކިޔަމަންވެ، ރުޖޫއަ ވީ މީހުންގެ މަގަށް ތަބާ ވާށެވެ! ދެން ތިޔަބައިމީހުން އެނބުރި ރުޖޫއަ ވުން ވަނީ ތިމަންރަސްކަލާނގެ ހަޒުރަތަށެވެ. ފަހެ، އޭރުން ތިޔަބައިމީހުން ކޮށްއުޅުނު ޢަމަލުތަކުގެ ޚަބަރު ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް އަންގަވާހުށީމެވެ.","",""],["","","","يا بني إنها إن تك مثقال حبة من خردل فتكن في صخرة أو في السماوات أو في الأرض يأت بها الله إن الله لطيف خبير","އޭ ދަރިފުޅާއެވެ! ހަމަކަށަވަރުން، އެ ޢަމަލަކީ ރެވިއޮށްޓަރެއްގެ ބަރުދަންހުރި ޢަމަލެއް ކަމުގައިވިޔަސް، ހިލައެއްގެ ތެރޭގައިވިޔަސް، ނުވަތަ އުޑުތަކުގައިވިޔަސް، ނުވަތަ ބިމުގެ ތެރޭގައިވިޔަސް (ގިޔާމަތް ދުވަހުން) ﷲ އެ ޢަމަލެއް ގެންނަވާނެތެވެ. ހަމަކަށަވަރުން، ﷲއީ، އޯގާވަންތަކަން ބޮޑު، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","يا بني أقم الصلاة وأمر بالمعروف وانه عن المنكر واصبر على ما أصابك إن ذلك من عزم الأمور","އޭ ދަރިފުޅާއެވެ! ތިބާ ނަމާދު ގާއިމުކުރާށެވެ! އަދި ހެޔޮކަންތަކަށް އަމުރުކުރާށެވެ! އަދި ނުބައިކަންތައް ނަހީކުރާށެވެ! ތިބާޔަށްޖެހޭ މުސީބަތަށް ކެތްކުރާށެވެ! ހަމަކަށަވަރުން، އެކަންވަނީ، ޢަޒުމު ކަނޑައަޅަންޖެހޭ ކަންތައްތަކުގެ ތެރެއިންނެވެ.","",""],["","","","ولا تصعر خدك للناس ولا تمش في الأرض مرحا إن الله لا يحب كل مختال فخور","އަދި މީސްތަކުންނަށް ކިބުރުވެރިވެ، ތިބާގެ ކޯތާފަތް އަނބުރައިނުލާށެވެ! (އެބަހީ: މޫނު އަނބުރައި ނުލާށެވެ!) އަދި ބޮޑާވެގެންވާ ޙާލު، ބިމުގައި ނުހިނގާށެވެ! ހަމަކަށަވަރުން، ކިބުރުވެރިވެ، ފަޚުރުވެރިވާ އެއްވެސް މީހަކުދެކެ ﷲ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["","","","واقصد في مشيك واغضض من صوتك إن أنكر الأصوات لصوت الحمير","އަދި ތިބާ ހިނގާ ހިނގުމުގައި މެދުމިނަށް ހިނގާށެވެ! އަދި ތިބާގެ އަޑު މަޑުކުރާށެވެ! ހަމަކަށަވަރުން، އަޑުތަކުގެ ތެރެއިން އެންމެ ހުތުރުވެގެންވާ އަޑަކީ ހިމާރުގެ އަޑުކަން ކަށަވަރެވެ.","",""],["","","","ألم تروا أن الله سخر لكم ما في السماوات وما في الأرض وأسبغ عليكم نعمه ظاهرة وباطنة ومن الناس من يجادل في الله بغير علم ولا هدى ولا كتاب منير","ހަމަކަށަވަރުން، އުޑުތަކާއި، ބިމުގައިވާހާ ތަކެއްޗެއް ﷲ ތިޔަބައިމީހުންނަށްޓަކައި ޚިދުމަތް ތެރިކުރެއްވިކަން، ތިޔަބައިމީހުންނަށް ނޭނގޭހެއްޔެވެ؟ އަދި އެކަލާނގެ ނިއުމަތްތައް ފާޅުވެގެންވާ ގޮތުގައްޔާއި، ފޮރުވިގެންވާ ގޮތުގައި ތިޔަބައިމީހުންގެ މައްޗަށް ފުރިހަމަކޮށްދެއްވިއެވެ. އަދި އެއްވެސް އިލްމަކާ ނުލައި، ނުވަތަ ތެދުމަގަކާ ނުލައި، ނުވަތަ އަލިކަން ދެނިވި ފޮތަކާ ނުލައި، ﷲއާމެދު ޖަދަލުކުރާ ބަޔަކު، މީސްތަކުންގެތެރެއިން ވެތެވެ.","",""],["","","","وإذا قيل لهم اتبعوا ما أنزل الله قالوا بل نتبع ما وجدنا عليه آباءنا أولو كان الشيطان يدعوهم إلى عذاب السعير","އަދި ﷲ ބާވައިލެއްވި އެއްޗަކަށް ތިޔަބައިމީހުން ތަބާ ވާށޭ އެއުރެންގެ ގާތުގައި ބުނެފިނަމަ، އެއުރެން ބުނާނެތެވެ. އަދި ކީއްހެއްޔެވެ؟ ތިމަންމެން ތަބާ ވާހުށީ، ތިމަންމެންގެ ކާބަފައިން އެގޮތެއްގެ މަތީގައި ތިބޭތީ ތިމަންމެންނަށް ފެނުނު ގޮތަށެވެ. ފަހެ، ނަރަކައިގެ އަޒާބަށް ޝައިތާނާ އެއުރެންނަށް ގޮވާކަމުގައިވިޔަސް ހެއްޔެވެ؟","",""],["","","","ومن يسلم وجهه إلى الله وهو محسن فقد استمسك بالعروة الوثقى وإلى الله عاقبة الأمور","އިހްސާން ތެރިވެ ހުންނަ ޙާލު، ﷲއަށް ކިޔަމަންވެ ކުރިމަތިލާ މީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާ އެންމެ ވަރުގަދަ އަގީދާގައި ހިފަހައްޓައިފިކަން ކަށަވަރެވެ. އަދި ކަންކަމުގެ ނިމުންވަނީ ﷲގެ ހަޒުރަތަށެވެ.","",""],["","","","ومن كفر فلا يحزنك كفره إلينا مرجعهم فننبئهم بما عملوا إن الله عليم بذات الصدور","އަދި ކާފިރު ވިމީހާ، އޭނާގެ ކާފިރުކަމުން ކަލޭގެފާނު ހިތާމަވެރިކުރުވިޔަ ނުދެއްވާށެވެ! އެއުރެން އެނބުރި ރުޖޫއަ ވާހުށީ، ހަމަ ތިމަންރަސްކަލާނގެ ހަޒުރަތަށެވެ. ފަހެ، އޭރުން އެއުރެން ކުރި ޢަމަލުތަކުގެ ޚަބަރު ތިމަންރަސްކަލާނގެ އެއުރެންނަށް އަންގަވާހުށީމެވެ. ހަމަކަށަވަރުން، ﷲއީ، ހިތްތަކުގައިވާހާ ކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","نمتعهم قليلا ثم نضطرهم إلى عذاب غليظ","ކުޑަހިނދުކޮޅަކަށް އެއުރެންނަށް ތިމަންރަސްކަލާނގެ (ދުނިޔޭގައި) އުފަލާއި، އަރާމު ދެއްވާހުށީމެވެ. ދެން ގަދަފަދަވެގެންވާ އަޒާބަކަށް އެއުރެން ހުށަހަޅުއްވާ ހުށީމެވެ.","",""],["","","","ولئن سألتهم من خلق السماوات والأرض ليقولن الله قل الحمد لله بل أكثرهم لا يعلمون","އަދި ހަމަކަށަވަރުން، އުޑުތަކާއި، ބިން ހެއްދެވީ ކާކުހޭ ކަލޭގެފާނު އެއުރެންނާ ސުވާލުކުރައްވައިފިނަމަ، އެއުރެން ބުނާނެކަން ކަށަވަރެވެ. ﷲއެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމްދު ހުރީ ﷲއަށެވެ. އަދި ކިއެއްތަ! އެއުރެން ކުރެ ގިނަމީހުންނަކަށް (އެކަމެއް) ނޭނގެތެވެ.","",""],["","","","لله ما في السماوات والأرض إن الله هو الغني الحميد","އުޑުތަކާއި، ބިމުގައިވާހާ އެއްޗެއް މަލަކަ ވެގެންވަނީ ﷲއަށެވެ. ހަމަކަށަވަރުން، ﷲއީ، ފުދިވޮޑިގެންވާ، ގިނަގިނައިން ހަމްދު ލިބިވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ولو أنما في الأرض من شجرة أقلام والبحر يمده من بعده سبعة أبحر ما نفدت كلمات الله إن الله عزيز حكيم","އަދި ހަމަކަށަވަރުން، ބިމުގައިވާހާ ގަސްގަހާގެއްސަކީ، ގަލަމް ތަކެއްކަމުގައި ވެފައި، އަދި ކަނޑު (ދެލިކަމުގައިވެފައި) އޭގެފަހަށް ހަތްކަނޑު އެއާއެކުވިޔަސް، ﷲގެ ކަލިމަފުޅުތައް (އެއިން ލިޔެ) ހުހެއް ނުވާނެތެވެ. ހަމަކަށަވަރުން، ﷲއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ما خلقكم ولا بعثكم إلا كنفس واحدة إن الله سميع بصير","ތިޔަބައިމީހުން ހެއްދެވުންވެސް، އަދި ތިޔަބައިމީހުން އަލުން ދިރުއްވައި ފޮނުއްވުންވެސް އެއް ނަފްސެއް (ހެއްދެވުން) ފަދައިން މެނުވީ ނުވެތެވެ. ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ألم تر أن الله يولج الليل في النهار ويولج النهار في الليل وسخر الشمس والقمر كل يجري إلى أجل مسمى وأن الله بما تعملون خبير","ހަމަކަށަވަރުން، ދުވާލުގެ ތެރެޔަށް ރޭގަނޑު ވައްދަވައި އަދި ރޭގަނޑުގެ ތެރެޔަށް ދުވާލު ވައްދަވައި އަދި އިރާއި ހަނދު، ޚިދުމަތް ތެރި ކުރެއްވީ، ﷲ ކަން ތިބާޔަކަށް ނޭނގޭހެއްޔެވެ؟ (އެއިން) ކޮންމެ އެއްޗެއް ކަނޑައަޅުއްވާފައިވާ މުއްދަތަކަށް ހިނގަހިނގާ ހުރެތެވެ. އަދި ހަމަކަށަވަރުން، ﷲއީ، ތިޔަބައިމީހުން ކުރާ ޢަމަލުތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ذلك بأن الله هو الحق وأن ما يدعون من دونه الباطل وأن الله هو العلي الكبير","އެހެނީ ހަމަކަށަވަރުން، ﷲއީ، ހައްގުވަންތަ ރަސްކަލާނގެއެވެ. އަދި ހަމަކަށަވަރުން، އެކަލާނގެ ފިޔަވައި އެއުރެން އަޅުކަންކުރާ ތަކެއްޗަކީ، ބާތިލު ތަކެއްޗެވެ. އަދި ހަމަކަށަވަރުން، ﷲއީ، އެންމެ މަތިވެރި، އެންމެ ޢަޡަމަތް ތެރި ރަސްކަލާނގެއެވެ.","",""],["","","","ألم تر أن الفلك تجري في البحر بنعمت الله ليريكم من آياته إن في ذلك لآيات لكل صبار شكور","ތިޔަބައިމީހުންނަށް އެކަލާނގެ އާޔަތްތައް ދެއްކެވުމަށްޓަކައި، ހަމަކަށަވަރުން، ﷲގެ ނިއުމަތުން ކަނޑުގައި ނާފަހަރު ދުވާތީ، ތިބާޔަކަށް ނުފެނޭހެއްޔެވެ؟ ހަމަކަށަވަރުން، ކެތްތެރިކަން ބޮޑު، ޝުކުރުވެރިވުން ބޮޑު، ކޮންމެ މީހަކަށް އެކަމުގައި ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","وإذا غشيهم موج كالظلل دعوا الله مخلصين له الدين فلما نجاهم إلى البر فمنهم مقتصد وما يجحد بآياتنا إلا كل ختار كفور","އަދި ހިޔާއަޅާ ފަރުބަދަތައްފަދަ ރާޅުތައް، އެއުރެން ވަށައިލައިފިނަމަ، އެކަލާނގެއަށް އީމާން ކަން ޚާލިސްކުރާ ޙާލުގައި، ﷲއަށް އެބައިމީހުން ދުއާކުރާނެތެވެ. އަދި އެކަލާނގެ، އެއުރެން ސަލާމަތްކުރައްވައި އެއްގަމަށް ގެންދަވައިފިހިނދު، ފަހެ، އެއުރެންގެ ތެރެއިން މެދުމިނު މީހުން ވެއެވެ. (އަދި ދެކޮޅުހަދާ މީހުންވެސް ވެއެވެ.) އަދި ކޮންމެ ޚިޔާނަތް ތެރި ކާފިރަކު މެނުވީ، ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް ދެކޮޅެއް ނަހަދާނެތެވެ.","",""],["","","","يا أيها الناس اتقوا ربكم واخشوا يوما لا يجزي والد عن ولده ولا مولود هو جاز عن والده شيئا إن وعد الله حق فلا تغرنكم الحياة الدنيا ولا يغرنكم بالله الغرور","އޭ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއަށް ތިޔަބައިމީހުން ތަގުވާވެރިވާށެވެ! އަދި އެދުވަހުގައި ބަފަޔަކަށް ދަރިޔެއްގެ މަތިން ކަމެއް ފުއްދައެއް ނުދެވޭނޭ، އަދި ދަރިޔަކަށްވެސް ބަފަޔަކަށް ކަމެއް ފުއްދައެއް ނުދެވޭނޭ ދުވަހަކަށް ތިޔަބައިމީހުން ބިރުވެތިވާށެވެ! ހަމަކަށަވަރުން، ﷲގެ ވައުދު ފުޅަކީ، ހައްގު ތެދެވެ. ފަހެ، ދުނިޔޭގެ ދިރިއުޅުން ތިޔަބައިމީހުން ހެއްލުންތެރިކުރިޔަ ނުދޭހުށިކަމެވެ! އަދި މަކަރުވެރި ޝައިތާނާ، ތިޔަބައިމީހުން ﷲއާމެދު ހެއްލުންތެރިކުރިޔަ ނުދޭހުށިކަމެވެ!","",""],["","","","إن الله عنده علم الساعة وينزل الغيث ويعلم ما في الأرحام وما تدري نفس ماذا تكسب غدا وما تدري نفس بأي أرض تموت إن الله عليم خبير","ހަމަކަށަވަރުން، ގިޔާމަތް ވުމުގެ ވަގުތު ދެނެވޮޑިގަތުން ވަނީ، ﷲގެ ހަޒުރަތު ގައެވެ. އަދި އެކަލާނގެ ވާރޭ ވެއްސަވަތެވެ. އަދި ރަޙިމު ތަކުގައިވާ ތަކެތި އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަދި އެއްވެސް ނަފްސަކަށް، އެ ނަފްސެއް މާދަމާ ހޯދައިގަންނާނީ ކޮންކަމެއްކަމެއް ނޭނގޭނެތެވެ. އަދި އެއްވެސް ނަފްސަކަށް އެ ނަފްސެއް މަރުވާނީ ކޮންބިމެއްގައި ކަމެއް ނޭނގޭނެތެވެ. ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޚައިބަރުވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم الم","ا ل م (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","تنزيل الكتاب لا ريب فيه من رب العالمين","މިއީ އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ބާވައިލެއްވި ފޮތެވެ. އެއާމެދު ޝައްކެއް ނެތެވެ.","",""],["","","","أم يقولون افتراه بل هو الحق من ربك لتنذر قوما ما أتاهم من نذير من قبلك لعلهم يهتدون","ނުވަތަ އެކަލޭގެފާނު އަމިއްލަފުޅަށް އެ ގުރްއާން ހެއްދެވިކަމަށް އެއުރެން ބުނަނީ ހެއްޔެވެ؟ އަދި ކިއެއްތަ! އެއީ ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައި ހައްގު ފޮތެވެ. އެއީ ކަލޭގެފާނުގެ ކުރިން އެބަޔަކަށް އިންޒާރުކުރައްވާނޭ ރަސޫލަކު ވަޑައިނުގަންނަވާ ގައުމެއްގެ ބަޔަކަށް ކަލޭގެފާނު އިންޒާރުކުރެއްވުމަށްޓަކައެވެ. (އެއީ) އެއުރެން ތެދުމަގު ލިބިގަތުމަށްޓަކައެވެ.","",""],["","","","الله الذي خلق السماوات والأرض وما بينهما في ستة أيام ثم استوى على العرش ما لكم من دونه من ولي ولا شفيع أفلا تتذكرون","ﷲއީ، އުޑުތަކާއި، ބިމާއި، އެދެމެދުގައި ވާހާ ތަކެތި ހަދުވަހުގެ ތެރޭގައި ހެއްދެވި ރަސްކަލާނގެއެވެ. ދެން ޢަރްޝުގެ މައްޗަށް އެކަލާނގެ އިސްތިވާވެ ވޮޑިގެންނެވިއެވެ. އެކަލާނގެ ފިޔަވައި ތިޔަބައިމީހުންނަށް އެހީތެރިވާނޭ ފަރާތެއް، އަދި ޝަފާއަތް ތެރިވާނޭ ފަރާތެއްވެސް ނުވެތެވެ. ފަހެ، ތިޔަބައިމީހުން ހަނދުމަ ނުކުރަނީ ހެއްޔެވެ؟","",""],["","","","يدبر الأمر من السماء إلى الأرض ثم يعرج إليه في يوم كان مقداره ألف سنة مما تعدون","އުޑުން ފެށިގެން ބިމާ ހަމަޔަށް ހުރިހާ ކަމެއް އެކަލާނގެ ތަދްބީރުކުރައްވަތެވެ. ދެން ތިޔަބައިމީހުން ގުނާގޮތުން އެއްހާސް އަހަރުގެ މިންވަރުގެ ދުވަހެއްގައި، އެހުރިހާ ކަމެއް އެކަލާނގެ ހަޒުރަތަށް އަރައިގެންދެއެވެ.","",""],["","","","ذلك عالم الغيب والشهادة العزيز الرحيم","އެކަލާނގެއީ، ނުފެންނަ ކަންތަކާއި، ފެންނަ ކަންތައް ދެނެވޮޑިގެންވާ، ޢަޒީޒުވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","الذي أحسن كل شيء خلقه وبدأ خلق الإنسان من طين","އެކަލާނގެއީ، ހުރިހާ އެއްޗެއް ފުރިހަމަ ސިފައިގައި ހެއްދެވި ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެ އިންސާނާ ހެއްދެވުން ފެއްޓެވީ މަށިންނެވެ.","",""],["","","","ثم جعل نسله من سلالة من ماء مهين","ދެން އެކަލާނގެ އެ އިންސާނާގެ ދަރިފަސްކޮޅު ދެރަވެގެންވާ ފެނެއްގެ ޚުލާޞާއަކުން ހެއްދެވިއެވެ.","",""],["","","","ثم سواه ونفخ فيه من روحه وجعل لكم السمع والأبصار والأفئدة قليلا ما تشكرون","ދެން އޭނާޔަށް ފުރިހަމަ ސިފަ ދެއްވައި، އެކަލާނގެ ރޫޙުފުޅުން އޭނާޔަށް ފުމެލެއްވިއެވެ. (އެބަހީ: ފުރާނަ އެޅުއްވިއެވެ.) އަދި އެކަލާނގެ ތިޔަބައިމީހުންނަށް އިވުމާއި، ފެނުމާއި، ހިތްތައް ލެއްވިއެވެ. ތިޔަބައިމީހުން ޝުކުރުކުރަނީ ވަރަށްވެސް މަދުންނެވެ.","",""],["","","","وقالوا أإذا ضللنا في الأرض أإنا لفي خلق جديد بل هم بلقاء ربهم كافرون","އެއުރެން ބުނޫއެވެ. ތިމަންމެން (މަރުވެ) ބިމުގެ ތެރޭގައި (ވެއްޔަށްވެ) ފޮރުވުނީމާ، އަލުން އާ އުފެދުމަކުން އުފެދޭނޭ ހެއްޔެވެ؟ އަދި ކީއްހެއްޔެވެ؟ އެއުރެންނީ، އެއުރެންގެ ވެރިރަސްކަލާނގެއާ ބައްދަލުވާނެކަމަށް ދެކޮޅު ހަދާ ބަޔެކެވެ.","",""],["","","","قل يتوفاكم ملك الموت الذي وكل بكم ثم إلى ربكم ترجعون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންގެ މަރުހިއްޕެވުން ޙަވާލުކުރައްވާފައިވާ މަލަކުލްމައުތު ތިޔަބައިމީހުންގެ މަރު ހިއްޕަވާނެތެވެ. ދެން ތިޔަބައިމީހުން ރުޖޫއަކުރައްވާހުށީ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","ولو ترى إذ المجرمون ناكسو رءوسهم عند ربهم ربنا أبصرنا وسمعنا فارجعنا نعمل صالحا إنا موقنون","އަދި ފާފަކުރި މީހުން، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި، ދެރަވެ އިސްޖަހައިގެން ތިބޭތަން ތިބާޔަށް ފެންނާނެ ނަމައެވެ. (އޭރުން ހައިރާން ވާފަދަ ކަންތައްތަކެއް ތިބާޔަށް ފެނުނީހެވެ. އެއުރެން ބުނާނެތެވެ.) އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެންނަށް ފެނިއްޖެއެވެ. އަދި އިވިއްޖެއެވެ. ފަހެ، އަޅަމެން ސާލިހު ޢަމަލުކުރުމަށް އަނބުރާ އަޅަމެން (ދުނިޔެއަށް) ފޮނުއްވާނދޭވެ! ހަމަކަށަވަރުން، އަޅަމެންނީ، ޔަގީންކުރާ ބަޔަކީމުއެވެ.","",""],["","","","ولو شئنا لآتينا كل نفس هداها ولكن حق القول مني لأملأن جهنم من الجنة والناس أجمعين","އަދި ތިމަންރަސްކަލާނގެ އިރާދަކުރެއްވިނަމަ، ކޮންމެ ނަފްސަކަށްމެ އެ ނަފްސެއްގެ ހިދާޔަތް ދެއްވީމުހެވެ. އެހެނެއްކަމަކު (ފާފަކުރާ) ޖިންނީންނާއި އިންސީން އެއްކޮށް، ހަމަކަށަވަރުން، ނަރަކަ ފުރުއްވާނޭކަމުގެ ބަސްފުޅު ތިމަންރަސްކަލާނގެ ހަޒުރަތުން އިސްވެގޮސްފައިވެއެވެ.","",""],["","","","فذوقوا بما نسيتم لقاء يومكم هذا إنا نسيناكم وذوقوا عذاب الخلد بما كنتم تعملون","ފަހެ، ތިޔަބައިމީހުންގެ މިދުވަހާ ބައްދަލުވާނޭކަން ތިޔަބައިމީހުން ހަނދާން ނައްތައިލި ކަމަށްޓަކައި، ތިޔަބައިމީހުން އަޒާބުގެ ރަހަ ލިބިގަންނާށެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންގެ މަތިން ހަނދުމަނެތި ކުރައްވައިފީމެވެ. އަދި ތިޔަބައިމީހުން ކޮށްއުޅުނު ޢަމަލު ތަކަށްޓަކައި ދެމިހުންނަނިވި އަޒާބުގެ ރަހަ، ތިޔަބައިމީހުން ލިބިގަންނާށެވެ!","",""],["","","","إنما يؤمن بآياتنا الذين إذا ذكروا بها خروا سجدا وسبحوا بحمد ربهم وهم لا يستكبرون","ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް އީމާން ވާކަން ކަށަވަރީ، އެ އާޔަތްތައް އެބަޔަކަށް ހަނދާންކޮށްދެވޭހިނދު، ސަޖިދަށް ތިރިވެ، އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ހަމްދާއެކު ތަސްބީހަ ކިޔާ މީހުންނެވެ. އަދި އެއުރެން ކިބުރުވެރިއެއް ނުވާނެތެވެ.","",""],["","","","تتجافى جنوبهم عن المضاجع يدعون ربهم خوفا وطمعا ومما رزقناهم ينفقون","އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ބިރުވެތިކަމާއި އުންމީދާއެކު ދުއާކުރާ ޙާލު، އެއުރެންގެ އަރިކަށިތައް (ރޭއަޅުކަންކުރުމަށްޓަކައި) ތަންމަތިތަކާ ފޭވެއެވެ. އަދި ތިމަންރަސްކަލާނގެ، އެއުރެންނަށް ދެއްވި ތަކެތީން، އެއުރެން ހޭދަކުރެތެވެ.","",""],["","","","فلا تعلم نفس ما أخفي لهم من قرة أعين جزاء بما كانوا يعملون","ފަހެ، އެއުރެންނަށްޓަކައި ފޮރުއްވާފައިވާ ލޮލުގެ ފިނިކަން (އެބަހީ: ލޮލަށް ފިނިކަންދެނިވި، ސުވަރުގޭގެ ނިއުމަތްތައް) އެއްވެސް ނަފްސަކަށް ނޭނގޭނެތެވެ. (އެއީ) އެއުރެން ކޮށްއުޅުނު ޢަމަލުތަކުގެ ޖަޒާއެއް ކަމުގައެވެ.","",""],["","","","أفمن كان مؤمنا كمن كان فاسقا لا يستوون","ފަހެ، މުއުމިނަކު ކަމުގައިވާ މީހާއާއި (އުރެދޭ) ފާސިގަކު ކަމުގައިވާ މީހާ އެއްފަދަހެއްޔެވެ؟ އެ ދެބައިމީހުން އެއްވަރެއް ނުވާނެތެވެ.","",""],["","","","أما الذين آمنوا وعملوا الصالحات فلهم جنات المأوى نزلا بما كانوا يعملون","އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަ މީހުން ދަންނާށެވެ! ފަހެ، އެއުރެން ކޮށްއުޅުނު ޢަމަލު ތަކަށްޓަކައި، ދެއްވާ ޝަރަފެއްގެ ގޮތުން، އެއުރެންނަށް ދެމިތިބޭނޭ ސުވަރުގެތައް ހުށްޓެވެ.","",""],["","","","وأما الذين فسقوا فمأواهم النار كلما أرادوا أن يخرجوا منها أعيدوا فيها وقيل لهم ذوقوا عذاب النار الذي كنتم به تكذبون","އަދި (ކާފިރުވެ) ފާސިގުވި މީހުން ދަންނާށެވެ! ފަހެ، އެއުރެން ތިބެނިވިތަނަކީ ނަރަކައެވެ. އެއުރެން އެތަނުން ނުކުންނަން އުޅެފި ކޮންމެ ފަހަރަކު، އެތަނަށް އެއުރެން އަނބުރާ އިއާދަކުރައްވާނެތެވެ. އަދި އެއުރެންނަށް އަންގަވާނެތެވެ. ތިޔަބައިމީހުން ދޮގުކޮށް އުޅުނު ނަރަކައިގެ އަޒާބުގެ ރަހަ، ތިޔަބައިމީހުން ލިބިގަންނާށެވެ!","",""],["","","","ولنذيقنهم من العذاب الأدنى دون العذاب الأكبر لعلهم يرجعون","އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެންމެބޮޑު އަޒާބު (އެބަހީ: ނަރަކައިގެ އަޒާބު) ފިޔަވައި ލުއި އަޒާބުން (އެބަހީ: ދުނިޔެމަތީގެ އަޒާބުން) އެއުރެންނަށް ރަހަ ދައްކަވާހުށީމެވެ. (އެއީ) އެއުރެން (އީމާންކަމަށް) ރުޖޫއަ ވުމަށްޓަކައެވެ.","",""],["","","","ومن أظلم ممن ذكر بآيات ربه ثم أعرض عنها إنا من المجرمين منتقمون","އެމީހެއްގެ ވެރިރަސްކަލާނގެ އާޔަތް ތަކުން އެމީހަކަށް ހަނދާންކޮށްދެއްވުމުން، ދެން އެ އާޔަތްތަކަށް ފުރަގަސްދީ އެނބުރިގަތް މީހަކަށްވުރެން އަނިޔާވެރިކަން ބޮޑީ ކާކުހެއްޔެވެ؟ ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، ކުށްވެރިންގެ ކިބައިން ބަދަލުހިއްޕަވާހުށީމެވެ.","",""],["","","","ولقد آتينا موسى الكتاب فلا تكن في مرية من لقائه وجعلناه هدى لبني إسرائيل","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް ފޮތް ދެއްވީމެވެ. ފަހެ، އެކަލޭގެފާނަށް އެ ފޮތް ލިބިވަޑައިގަތްކަމާމެދު ކަލޭގެފާނު ޝައްކުކަމެއްގައި ވެވަޑައިނުގަންނަވާށެވެ! އަދި އިސްރާއީލުގެދަރިންނަށް ހިދާޔަތެއް ކަމުގައި ތިމަންރަސްކަލާނގެ އެ ފޮތް ލެއްވީމެވެ.","",""],["","","","وجعلنا منهم أئمة يهدون بأمرنا لما صبروا وكانوا بآياتنا يوقنون","އަދި އެއުރެން ކެތްތެރިވީހިނދު، ތިމަންރަސްކަލާނގެ އަމުރު ފުޅަށް ތެދުމަގު ދައްކަވާ އިމާމުންތަކެއް ތިމަންރަސްކަލާނގެ އެއުރެންގެ ތެރެއިން ލެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާމެދު ޔަގީންކުރާ ކަމުގައި އެއުރެން ވޫއެވެ.","",""],["","","","إن ربك هو يفصل بينهم يوم القيامة فيما كانوا فيه يختلفون","ހަމަކަށަވަރުން، އެއުރެން ޚިލާފު ވެގެން އުޅުނު ކަންތައްތަކާމެދު، ގިޔާމަތް ދުވަހުން ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެއުރެންގެ މެދުގައި ނިޔާކަނޑައަޅުއްވާނެތެވެ.","",""],["","","","أولم يهد لهم كم أهلكنا من قبلهم من القرون يمشون في مساكنهم إن في ذلك لآيات أفلا يسمعون","އަދި އެއުރެންގެ ކުރިން ތިމަންރަސްކަލާނގެ ކިތައްކިތައް އުއްމަތް ހަލާކުކުރެއްވިކަން އެއުރެންނަށް ބަޔާން ވެގެން ނުވޭހެއްޔެވެ؟ އެއުރެންގެ ގޮވަތިގެދޮރުހުރި ތަންތާނގައި އެއުރެން ހިނގަހިނގާއުޅޭ ޙާލު ގައެވެ. ހަމަކަށަވަރުން، އެކަމުގައި ހެކިތަކެއްވާކަން ކަށަވަރެވެ. ފަހެ، އެއުރެން އަޑުނާހަނީ ހެއްޔެވެ؟","",""],["","","","أولم يروا أنا نسوق الماء إلى الأرض الجرز فنخرج به زرعا تأكل منه أنعامهم وأنفسهم أفلا يبصرون","އަދި ގަހެއް ރުކެއް ނެތް ހިކި ބިމަށް، ތިމަންރަސްކަލާނގެ ފެން ފޮނުއްވައި، އެއިން އެއުރެންގެ ޖަނަވާރުތަކާއި ޚުދެއުރެން ކައިއުޅޭ ގަސްގަހާގެހި ނެރުއްވާކަން އެއުރެންނަށް ނޭނގެނީހެއްޔެވެ؟ (އެކަލާނގެ ކުޅަދުންވަންތަކަން) އެއުރެންނަށް ނުފެންނަނީ ހެއްޔެވެ؟","",""],["","","","ويقولون متى هذا الفتح إن كنتم صادقين","އެއުރެން ބުނެތެވެ. ތިޔަބައިމީހުންނީ، ތެދުބުނާމީހުން ކަމުގައި ވަނީނަމަ، ތިޔަ ފައިޞަލާ ވާނީ ކޮންއިރަކުން ހެއްޔެވެ؟","",""],["","","","قل يوم الفتح لا ينفع الذين كفروا إيمانهم ولا هم ينظرون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ނިޔާ އިއްވަވާ ދުވަހު (އެބަހީ: ގިޔާމަތް ދުވަހުން) ކާފިރުވި މީހުންނަކަށް އެއުރެން އީމާން ވުމަކުން މަންފާއެއް ނުކުރާނެތެވެ. އަދި އެއުރެންނަކަށް މުހުލަތެއްވެސް ނުމެދެއްވާނޭމެއެވެ.","",""],["","","","فأعرض عنهم وانتظر إنهم منتظرون","ފަހެ، ކަލޭގެފާނު އެއުރެންނާ އެއްކިބާވެވަޑައިގަންނަވާށެވެ! އަދި ކަލޭގެފާނު އިންތިޒާރުކުރައްވާށެވެ! ހަމަކަށަވަރުން، އެއުރެންވެސް އިންތިޒާރުކުރެތެވެ.","",""],["","","","بسم الله الرحمن الرحيم يا أيها النبي اتق الله ولا تطع الكافرين والمنافقين إن الله كان عليما حكيما","އޭ ނަބިއްޔާއެވެ! ކަލޭގެފާނު ﷲއަށް ތަގުވާވެރިވެވަޑައިގަންނަވާށެވެ! އަދި ކާފިރްނާއި، މުނާފިގުންނަށް ކަލޭގެފާނު ކިޔަމަންވެވަޑައިނުގަންނަވާށެވެ! ހަމަކަށަވަރުން، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ކަލާނގެ ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","واتبع ما يوحى إليك من ربك إن الله كان بما تعملون خبيرا","އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތު ންކަލޭގެފާނަށް އިއްވަވާ ވަހީއަށް ކަލޭގެފާނު ތަބާ ވެވަޑައިގަންނަވާށެވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ކުރާ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","وتوكل على الله وكفى بالله وكيلا","އަދި ކަލޭގެފާނު ﷲއަށް ވަކީލުކުރައްވާށެވެ! ވަކީލަކު ކަމުގައި ﷲ ފުދިވޮޑިގެންވެއެވެ.","",""],["","","","ما جعل الله لرجل من قلبين في جوفه وما جعل أزواجكم اللائي تظاهرون منهن أمهاتكم وما جعل أدعياءكم أبناءكم ذلكم قولكم بأفواهكم والله يقول الحق وهو يهدي السبيل","އެއްވެސް މީހަކަށް، އެމީހެއްގެ އެތެރެހަށީގައި، ﷲ ދެ ހިތެއް ނުލައްވައެވެ. އަދި ތިޔަބައިމީހުންގެ އަނބިންގެ ތެރެއިން، ތިޔަބައިމީހުން ޡުހާރުކުރާ (އެބަހީ: މަޔަކާ ހަމަކުރާ) އަނބިންނަކީ، ތިޔަބައިމީހުންގެ މައިން ކަމުގައިވެސް ނުލައްވަތެވެ. އަދި ތިޔަބައިމީހުންގެ ދަރިން ކަމުގައި ހަދައިގެންއުޅޭ ދަރިންނަކީ، ތިޔަބައިމީހުންގެ ދަރިން ކަމުގައިވެސް ނުލައްވަތެވެ. އެއީ ތިޔަބައިމީހުންގެ އަނގަތަކުން ބުނާ ބުނުމެކެވެ. އަދި ﷲ ހައްގު ބަސްފުޅު ވަހީކުރައްވަތެވެ. އަދި އެކަލާނގެ ތެދުމަގަށް މަގު ދައްކަވަތެވެ.","",""],["","","","ادعوهم لآبائهم هو أقسط عند الله فإن لم تعلموا آباءهم فإخوانكم في الدين ومواليكم وليس عليكم جناح فيما أخطأتم به ولكن ما تعمدت قلوبكم وكان الله غفورا رحيما","އެ ދަރިން އެއުރެންގެ ބަފައިންނަށް ނިސްބަތްކުރާށެވެ! އެގޮތް ﷲގެ ހަޒުރަތުގައި ޢަދުލުވެރިކަން ބޮޑެވެ. އެ ދަރިންގެ ބަފައިން ތިޔަބައިމީހުންނަށް ނޭނގޭނަމަ، ފަހެ، އެއީ ދީންގެ ފަރާތުން ތިޔަބައިމީހުންގެ އަޚުންނެވެ. އަދި ތިޔަބައިމީހުންގެ އެހީތެރިންނެވެ. އަދި ތިޔަބައިމީހުންނަށް ނޭނގިގެން (ކުށުން) ކުރެވުނު ކަމެއްގެ ފާފައެއް ތިޔަބައިމީހުންގެ މައްޗަކަށް ނެތެވެ. އެހެނެއްކަމަކު، ފާފަވެރިކަން އޮންނާނީ ތިޔަބައިމީހުންގެ ހިތްތައް ގަސްދުކުޅަ ކަމަކާ މެދުގައެވެ. އަދި ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","النبي أولى بالمؤمنين من أنفسهم وأزواجه أمهاتهم وأولو الأرحام بعضهم أولى ببعض في كتاب الله من المؤمنين والمهاجرين إلا أن تفعلوا إلى أوليائكم معروفا كان ذلك في الكتاب مسطورا","މުއުމިނުންނަށް އެއުރެންގެ އަމިއްލަ ނަފްސު ތަކަށްވުރެން، ނަބިއްޔާ އައުލާ ކަން ބޮޑެވެ. އަދި އެ ނަބިއްޔާގެ އަނބިއަނބިކަނބަލުންނީ، އެއުރެންގެ މައިންނެވެ. މުއުމިންނާއި، މުހާޖިރުންގެ ތެރެއިންވާ މީހުންނަށްވުރެން ﷲގެ ފޮތުގައި ކަނޑައަޅުއްވާފައިވާ ގޮތުގައި، ގާތްތިމާގެ މީހުން އޭގެއެއްބަޔަކު އަނެއްބަޔަކާ އައުލާ ކަން ބޮޑެވެ. ތިޔަބައިމީހުންގެ އެކުވެރިންނަށް ހެޔޮކަމެއް ކުރުމުގެގޮތުން ބާއްވާ ގުޅުމެއް މެނުވީއެވެ. ފޮތުގައި (އެބަހީ: އައްލައުޙުލް މަޙްފޫޡުގައި) ލިޔުއްވާފައިވާ ކަމެއްކަމުގައި އެކަންތައް ވިއެވެ.","",""],["","","","وإذ أخذنا من النبيين ميثاقهم ومنك ومن نوح وإبراهيم وموسى وعيسى ابن مريم وأخذنا منهم ميثاقا غليظا","ނަބީބޭކަލުންގެ ކިބައިންނާއި، ކަލޭގެފާނާއި ނޫޙުގެފާނާއި، އިބްރާހީމްގެފާނާއި، މޫސާގެފާނާއި، މަރިޔަމްގެފާނުގެ ދަރިކަލުން ޢީސާގެފާނުގެ ކިބައިން ތިމަންރަސްކަލާނގެ ކަށަވަރުވެގެންވާ އަހުދު ހިއްޕެވިހިނދު ހަނދުމަކުރާށެވެ! އަދި އެބޭކަލުންގެ ކިބައިން ގަދަވެ ކަށަވަރުވެގެންވާ އަހުދު، ތިމަންރަސްކަލާނގެ ހިއްޕެވީމެވެ.","",""],["","","","ليسأل الصادقين عن صدقهم وأعد للكافرين عذابا أليما","(އެއީ) ތެދުވެރިންގެ ކިބައިން، އެބޭކަލުންގެ ތެދުވެރިކަމާމެދު ސުވާލުކުރެއްވުމަށްޓަކައެވެ. އަދި ކާފިރުންނަށްޓަކައި ވޭންދެނިވި އަޒާބު އެކަލާނގެ ތައްޔާރު ކުރައްވާފައިވެއެވެ.","",""],["","","","يا أيها الذين آمنوا اذكروا نعمة الله عليكم إذ جاءتكم جنود فأرسلنا عليهم ريحا وجنودا لم تروها وكان الله بما تعملون بصيرا","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ލަޝްކަރު ތަކެއް ތިޔަބައިމީހުންނާ ހަމަޔަށް އައިހިނދު، ﷲ ތިޔަބައިމީހުންނަށް ދެއްވި ނިއުމަތް ތިޔަބައިމީހުން ހަނދާންކުރާށެވެ! ފަހެ، އެހިނދު އެއުރެންގެ މައްޗަށް ގަދަ ވަޔަކާއި، ތިޔަބައިމީހުންނަށް ނުފެންނަ ލަޝްކަރު ތަކެއް ތިމަންރަސްކަލާނގެ ފޮނުއްވީމެވެ. ތިޔަބައިމީހުން ކަންތައްކުރާގޮތް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ކަލަކުކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","إذ جاءوكم من فوقكم ومن أسفل منكم وإذ زاغت الأبصار وبلغت القلوب الحناجر وتظنون بالله الظنونا","ތިޔަބައިމީހުންގެ މަތިންނާއި، ތިރިން (އެބަހީ: ނަޖުދު ކަރަވީ ފަރާތާއި މައްކާ ވީފަރާތުން) އެއުރެން އައިހިނދެވެ. އަދި ލޯތައް ބޮޑުވެ (ކަންބޮޑުވުމުގެ ސަބަބުން) ލަގޮނޑިވަޅުތަކާ ހަމަޔަށް ހިތްތައް އައިހިނދެވެ. އަދި ތިޔަބައިމީހުން ﷲއާމެދު ހީތައް ކުޅަހިނދެވެ.","",""],["","","","هنالك ابتلي المؤمنون وزلزلوا زلزالا شديدا","އެވަގުތު މުއުމިނުން އިމްތިހާނުކުރެއްވިއެވެ. އަދި ގަދަވެގެންވާ ގުޑުމަކުން އެއުރެންނަށް ގުޑުން އަރައިގެން ދިޔައެވެ. (އެބަހީ: އެއުރެންގެ ސާބިތުކަން ގެއްލި، އެގޮތް މިގޮތް ވެގެންދިޔައެވެ.)","",""],["","","","وإذ يقول المنافقون والذين في قلوبهم مرض ما وعدنا الله ورسوله إلا غرورا","އަދި މުނާފިގްނާއި، އެއުރެންގެ ހިތްތަކުގައި ބަލިމަޑުކަމެއްވާ މީހުން ބުނާހިނދެވެ. ﷲއާއި، އެކަލާނގެ ރަސޫލާ، ތިމަންމެންނަށް ކެހިވެރި ވައުދަކުން މެނުވީ ވައުދެއް ނުކުރައްވަތެވެ.","",""],["","","","وإذ قالت طائفة منهم يا أهل يثرب لا مقام لكم فارجعوا ويستأذن فريق منهم النبي يقولون إن بيوتنا عورة وما هي بعورة إن يريدون إلا فرارا","އަދި އެއުރެންގެ ތެރެއިން ބަޔަކު ބުނިހިނދު، ހަނދުމަކުރާށެވެ! އޭ ޔަޘްރިބުގެ (އެބަހީ: އަލްމަދީނާގެ) އަހުލުވެރިންނޭވެ! ތިޔަބައިމީހުންނަކަށް ތިބުމުގެ ތަނެއް ނެތެވެ. ފަހެ، ތިޔަބައިމީހުން އެނބުރި ހިނގައިދާށެވެ! އަދި އޭގެތެރެއިން ބަޔަކު ނަބިއްޔާގެ އަރިހުން އިޒުނަށް އެދެތެވެ. އެއުރެން ބުނެތެވެ. ހަމަކަށަވަރުން، ތިމަންމެންގެ ގެތަކަކީ ނިވަލެއްނެތް ތަނެކެވެ. އެއީ ނިވަލެއްނެތް ތަނެއްނޫނެވެ. ފިލައިގެންދިޔުން މެނުވީ އެއުރެން ނޭދެތެވެ.","",""],["","","","ولو دخلت عليهم من أقطارها ثم سئلوا الفتنة لآتوها وما تلبثوا بها إلا يسيرا","އެއުރެންގެ ކައިރިޔަށް އެރަށުގެ ހުރިހާ ފަރާތަކުން އަދުއްވުން އަރައި، ދެން އެއުރެންގެ ކިބައިން ފިތުނަވެރިކަމަށް އެދުނުނަމަ، އެކަން އެއުރެން ގެނެސްގަތީހެވެ. އަދި އެއުރެން އެރަށުގައި ކުޑަހިނދުކޮޅަކަށް މެނުވީ ލަސްވެ ނުތިބީހެވެ.","",""],["","","","ولقد كانوا عاهدوا الله من قبل لا يولون الأدبار وكان عهد الله مسئولا","އަދި ހަމަކަށަވަރުން، އެއުރެން ފުރަގަސްދީ ނުދާނެކަމަށް މީގެކުރިން ﷲގެ ހަޒުރަތަށް އަހުދު ކޮށްފައިވިއެވެ. އަދި ﷲއަށް ކުރާ އަހުދަކީ (އެއާމެދު) ސުވާލުކުރައްވާނެ ކަމެއްކަމުގައި ވެއެވެ.","",""],["","","","قل لن ينفعكم الفرار إن فررتم من الموت أو القتل وإذا لا تمتعون إلا قليلا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ފިލައިދިއުމަކުން ތިޔަބައިމީހުންނަކަށް މަންފާއެއް ނުކުރާނެތެވެ. ތިޔަބައިމީހުން މަރުން ނުވަތަ ގަތުލު ވުމުން ފިލިޔަސް، ކުޑަހިނދުކޮޅަކަށް މެނުވީ ދުނިޔޭގައި އަރާމެއް ނުކުރެވޭނެތެވެ.","",""],["","","","قل من ذا الذي يعصمكم من الله إن أراد بكم سوءا أو أراد بكم رحمة ولا يجدون لهم من دون الله وليا ولا نصيرا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންނަށް ނުބައިގޮތެއް މެދުވެރިކުރެއްވުމަށް ﷲ އިރާދަކުރައްވައިފިނަމަ، ނުވަތަ ތިޔަބައިމީހުންނަށް ރަހުމަތެއް ލެއްވުމަށް އެކަލާނގެ އިރާދަކުރައްވައިފިނަމަ، އެކަލާނގެ ހަޒުރަތުން ތިޔަބައިމީހުން ރައްކާތެރިކޮށް މަނާކުރާނެ މީހަކީ ކާކުހެއްޔެވެ؟ އަދި ﷲ ފިޔަވައި އެއުރެންނަށް ވާގިދޭނެ މީހަކު ނުވަތަ ނަސްރު ދޭނެމީހަކުވެސް އެއުރެންނަކަށް ނުފެންނާނެތެވެ.","",""],["","","","قد يعلم الله المعوقين منكم والقائلين لإخوانهم هلم إلينا ولا يأتون البأس إلا قليلا","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ތެރެއިން ހުރަސްއަޅާ މީހުންނާއި، އަދި އެއުރެންގެ އަޚުންގެ ގާތުގައި ތިމަންމެންގެ ކައިރިޔަށް އަންނާށޭ ބުނާ މީހުން ﷲ ދެނެވޮޑިގެންވެތެވެ. އަދި އެއުރެން ވަރަށް މަދުން މެނުވީ ހަނގުރާމަޔަކަށް ނާންނާނެތެވެ.","",""],["","","","أشحة عليكم فإذا جاء الخوف رأيتهم ينظرون إليك تدور أعينهم كالذي يغشى عليه من الموت فإذا ذهب الخوف سلقوكم بألسنة حداد أشحة على الخير أولئك لم يؤمنوا فأحبط الله أعمالهم وكان ذلك على الله يسيرا","(އެއީ) ތިޔަބައިމީހުންގެ މައްޗަށް (ހޭދައެއް ކުރުމަށް، ނުވަތަ އެހީއެއް ވުމަށް) ބަޚީލު ވުމަށްޓަކައެވެ. ފަހެ، އެއުރެންނަށް ބިރުވެރިކަމެއް އަންނަހިނދު، މަރުގެ ސަކަރާތުގައި ހޭނެތިފައިވާ މީހަކު ފަދައިން، އެއުރެންގެ ލޯތައް އެނބުރި އެނބުރި ހުންނަ ޙާލުގައި، ކަލޭގެފާނާ ދިމާޔަށް އެއުރެން ބަލާތީ ކަލޭގެފާނަށް ފެނިވަޑައިގަންނަވާނެތެވެ. އަދި ބިރުވެރިކަން ފިލައިދިއުމުން (ޖެއްސުމާއި މަލާމާތުގެ) ތޫނު ދޫތަކަކުން ތިޔަބައިމީހުންނަށް އެއްޗެހި ގޮވާނެތެވެ. (ޣަނީމާ މުދަލާއި، އެހެނިހެން) މުދަލަށް ދަހިވެތިވާ ޙާލު ގައެވެ. އެއުރެން އީމާނެއް ނުވެތެވެ. ފަހެ، ﷲއެއުރެންގެ ޢަމަލުތައް ބާތިލުކުރެއްވިއެވެ. އަދި އެކަމަކީ، ﷲއަށް ދާދިފަސޭހަކަމެއް ކަމުގައިވެއެވެ.","",""],["","","","يحسبون الأحزاب لم يذهبوا وإن يأت الأحزاب يودوا لو أنهم بادون في الأعراب يسألون عن أنبائكم ولو كانوا فيكم ما قاتلوا إلا قليلا","(ކާފިރުންގެ) ޖަމާއަތްތައް އެނބުރި (މައްކާއަށް) ނުދާކަމަށް އެއުރެން (އެބަހީ: މުނާފިގުން) ހީކުރެތެވެ. އަދި އެ ޖަމާއަތްގެ މީހުން އަތުވެއްޖެނަމަ، އަޢުރާބީންގެ ތެރޭގައި ސަހަރާގައި އެއުރެންވީނަމަ، ކިހާރަނގަޅުވީސްހޭ ބުނެ، އެއުރެން އުންމީދުކުރެއެވެ. އެއުރެން ތިޔަބައިމީހުންގެ ޚަބަރުތައް އަހައި އޮޅުންފިލުވަތެވެ. އަދި ތިޔަބައިމީހުންގެ ތެރޭގައި އެއުރެންވީނަމަ، ވަރަށްމަދުން މެނުވީ، އެއުރެން ހަނގުރާމައެއް ނުކުރީހެވެ.","",""],["","","","لقد كان لكم في رسول الله أسوة حسنة لمن كان يرجو الله واليوم الآخر وذكر الله كثيرا","ހަމަކަށަވަރުން، ﷲގެ ރަސޫލާގެ ކިބައިގައި، ތިޔަބައިމީހުންނަށް ރިވެތިވެގެންވާ ނަމޫނާއެއްވެއެވެ. (އެއީ) ﷲގެ ދަރުމައާއި، އާޚިރަތްގެ ސަވާބަށް އެދޭ، އަދި ގިނަގިނައިން ﷲ ހަނދުމަކުރާ ކަމުގައިވާ މީހަކަށެވެ.","",""],["","","","ولما رأى المؤمنون الأحزاب قالوا هذا ما وعدنا الله ورسوله وصدق الله ورسوله وما زادهم إلا إيمانا وتسليما","އަދި (ކާފިރުންގެ) ޖަމާއަތްތައް މުއުމިނުންނަށް ފެނުނުހިނދު، އެއުރެން ބުނޫއެވެ. މިއީ ތިމަންމެންނަށް ﷲއާއި، އެކަލާނގެ ރަސޫލާ ވައުދުކުރެއްވި ކަންތަކެވެ. އަދި ﷲއާއި، އެކަލާނގެ ރަސޫލާ އިއްވެވީ ތެދުބަހެވެ. އަދި އެއުރެންނަކަށް އެކަމުގެ ސަބަބުން އީމާންކަމާއި، ކިޔަމަންތެރިކަން މެނުވީ އިތުރެއް ނުވެތެވެ.","",""],["","","","من المؤمنين رجال صدقوا ما عاهدوا الله عليه فمنهم من قضى نحبه ومنهم من ينتظر وما بدلوا تبديلا","ﷲއަށް އެއުރެން އަހުދު ވީ ކަންތަކަށް ތެދުވެރިވީ ފިރިހެނުންތަކެއް މުއުމިނުންގެ ތެރެއިންވެއެވެ. ފަހެ، އެއުރެންގެ ތެރެއިން (ޝަހީދުވެ) މަރުވެގެންދިޔަބަޔަކު ވެއެވެ. އަދި (ޝަހީދު ވުމަށް) އިންތިޒާރުކުރާ ބަޔަކުވެސް އެއުރެންގެ ތެރެއިން ވެއެވެ. އަދި އެއުރެން (އެ އަހުދަކަށް) އެއްވެސްކަހަލަ ބަދަލެއް ނުގެނެތެވެ.","",""],["","","","ليجزي الله الصادقين بصدقهم ويعذب المنافقين إن شاء أو يتوب عليهم إن الله كان غفورا رحيما","(އެއީ) ތެދުވެރިވީ މީހުންނަށް، އެއުރެން ތެދުވެރިވީކަމަށްޓަކައި، ﷲ ހެޔޮ ޖަޒާދެއްވުމަށާއި، އެކަލާނގެ އިރާދަކުރައްވައިފިނަމަ، މުނާފިގުންނަށް އަޒާބު ދެއްވުމަށް، ނުވަތަ އެއުރެންގެ މައްޗަށް ތައުބާ ލެއްވުމަށެވެ. ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެ ކަމުގައިވެއެވެ.","",""],["","","","ورد الله الذين كفروا بغيظهم لم ينالوا خيرا وكفى الله المؤمنين القتال وكان الله قويا عزيزا","ކާފިރުވި މީހުން އެއުރެންގެ ރުޅިވެރިކަމާއެކު ﷲ (އެއުރެން) ރައްދުކުރެއްވިއެވެ. އެއުރެންނަކަށް އެއްވެސް ހެވެއް ނުލިބުނެވެ. އަދި ﷲ މުއުމިނުންނަށް ހަނގުރާމަކުރުން ފުއްދަވައި ދެއްވައިފިއެވެ. (އެބަހީ: އެއުރެން ގަދަހަނގުރާމައެއް ނުކޮށް އެކަން ނިމިއްޖެއެވެ.) އަދި ﷲއީ، ބާރުވެރިވަންތަ، ޢަޒީޒުވަންތަ ރަސްކަލާނގެ ކަމުގައިވެއެވެ.","",""],["","","","وأنزل الذين ظاهروهم من أهل الكتاب من صياصيهم وقذف في قلوبهم الرعب فريقا تقتلون وتأسرون فريقا","އަދި އެކަލާނގެ، ފޮތުގެ އަހުލުވެރިންކުރެ އެއުރެންނަށް ވާގިދިން މީހުން، އެއުރެންގެ ކިއްލާތަކުން ބޭލުއްވިއެވެ. އަދި އެއުރެންގެ ހިތްތަކަށް ބިރުވެރިކަން ވެއްދެވިއެވެ. ތިޔަބައިމީހުން (އޭގެ) އެއްބަޔަކު ގަތުލުކުރަމުން ގެންދިޔައީމުއެވެ. އަދި އަނެއްބަޔަކު ހައްޔަރުކުރަމުން ގެންދިޔައީމުއެވެ.","",""],["","","","وأورثكم أرضهم وديارهم وأموالهم وأرضا لم تطئوها وكان الله على كل شيء قديرا","އަދި އެއުރެންގެ ބިމާއި، އެއުރެންގެ ގެދޮރާއި، އެއުރެންގެ މުދަލާއި، ތިޔަބައިމީހުން އެ ބިމުގައި ފައިތިލަވެސް ޖައްސައިނުލާ ބިމެއް ތިޔަބައިމީހުންނަށް އެކަލާނގެ ލިބިދެއްވިއެވެ. އަދި ﷲއީ، ކޮންމެ ކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ކަލަކު ކަމުގައި ވެއެވެ.","",""],["","","","يا أيها النبي قل لأزواجك إن كنتن تردن الحياة الدنيا وزينتها فتعالين أمتعكن وأسرحكن سراحا جميلا","އޭ ނަބިއްޔާއެވެ! ކަލޭގެފާނުގެ އަނބިއަނބިކަނބަލުންނަށް ވިދާޅުވާށެވެ! ތިޔަކަނބަލުން ދުނިޔޭގެ ހަޔާތާއި، އެތާނގެ ޒީނަތްތެރިކަން އެދޭކަމަށްވާނަމަ، އަންނާށެވެ! ތިޔަކަނބަލުންނަށް މުތުއާ ދެއްވާހުށީމެވެ. އަދި ރިވެތިވެގެންވާ ވަރިކުރެއްވުމަކުން ތިޔަކަނބަލުން ވަރިކުރައްވާ ހުށީމެވެ.","",""],["","","","وإن كنتن تردن الله ورسوله والدار الآخرة فإن الله أعد للمحسنات منكن أجرا عظيما","އަދި ތިޔަކަނބަލުން، ﷲއާއި، އެކަލާނގެ ރަސޫލާއާއި، އާޚިރަތްގެ ގޮވަތި އެދޭކަމުގައިވާނަމަ، ފަހެ، ހަމަކަށަވަރުން، ﷲ، ތިޔަކަނބަލުންކުރެ އިހްސާން ތެރިންނަށް ބޮޑުވެގެންވާ ދަރުމަ ތައްޔާރު ކުރައްވާފައިވެއެވެ.","",""],["","","","يا نساء النبي من يأت منكن بفاحشة مبينة يضاعف لها العذاب ضعفين وكان ذلك على الله يسيرا","އޭ ނަބިއްޔާގެ އަނބިއަނބިކަނބަލުންނޭވެ! ތިޔަކަނބަލުންކުރެ ފާޅުވެގެންހުރި ހުތުރުކަން ބޮޑު ފާފަޔެއްކުރި މީހަކަށް ދެގުނަޔަށް އަޒާބު އިތުރުކުރައްވާ ހުށްޓެވެ. އަދި އެކަންތަކަކީ، ﷲއަށް ދާދިފަސޭހަ ކަމެއް ކަމުގައިވެއެވެ.","",""],["","","","ومن يقنت منكن لله ورسوله وتعمل صالحا نؤتها أجرها مرتين وأعتدنا لها رزقا كريما","އަދި ތިޔަކަނބަލުންގެ ތެރެއިން ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް ކިޔަމަންތެރިވެ ސާލިހު ޢަމަލުކުރާ މީހަކަށް، އެމީހާގެ ދަރުމަ، ތިމަންރަސްކަލާނގެ ދެގުނަޔަށް ދެއްވާހުށީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އެމީހަކަށްޓަކައި (ސުވަރުގޭގައި) ދީލަތި ދެއްވުމެއް ތައްޔާރު ކުރެއްވީމެވެ.","",""],["","","","يا نساء النبي لستن كأحد من النساء إن اتقيتن فلا تخضعن بالقول فيطمع الذي في قلبه مرض وقلن قولا معروفا","އޭ ނަބިއްޔާގެ އަނބިއަނބިކަނބަލުންނޭވެ! ތިޔަކަނބަލުން (އެހެން) އަންހެނުންގެ ތެރެއިން އެކަކާވެސް އެއްފަދަ ބަޔަކު ކަމުގައި ނުވަމުއެވެ. ތިޔަކަނބަލުން (ﷲއަށް) ތަގުވާވެރިވެއްޖެނަމައެވެ. ފަހެ، ތިޔަކަނބަލުން ލޫޅާފަތި އަޑަކުން ވާހަކަ ނުދައްކާށެވެ! (އެއީ) ހިތުގެތެރޭގައި (ނިފާގުގެ) ބަލިމަޑުކަމެއްހުރި މީހަކު ދަހިވެތިވެދާނެތީއެވެ. އަދި ތިޔަކަނބަލުން ރަނގަޅު ބަހުން ބަސްބުނާށެވެ!","",""],["","","","وقرن في بيوتكن ولا تبرجن تبرج الجاهلية الأولى وأقمن الصلاة وآتين الزكاة وأطعن الله ورسوله إنما يريد الله ليذهب عنكم الرجس أهل البيت ويطهركم تطهيرا","އަދި ތިޔަކަނބަލުން، ތިޔަކަނބަލުންގެ ގެތަކުގައި ތިބޭށެވެ! އިހުގެ ޖާހިލީ ޒަމާނުގެ ޒީނަތުން ތިޔަކަނބަލުން ޒީނަތްތެރި ނުވާހުށިކަމެވެ! އަދި ތިޔަކަނބަލުން ނަމާދު ގާއިމުކުރާށެވެ! އަދި ތިޔަކަނބަލުން ޒަކާތް ދޭށެވެ! އަދި ﷲއާއި، އެކަލާނގެ ރަސޫލާއަށް ތިޔަކަނބަލުން ކިޔަމަންވާށެވެ! އޭ އަހުލުބައިތުންނޭވެ! ﷲ އިރާދަކުރައްވާކަން ކަށަވަރީ، ތިޔަބައިމީހުންގެ ކިބައިން ފާފަތައް ދުރުކުރައްވައި، ފުރިހަމަ ތާހިރުކުރެއްވުމަކުން ތިޔަބައިމީހުން ތާހިރުކުރެއްވުމަށެވެ.","",""],["","","","واذكرن ما يتلى في بيوتكن من آيات الله والحكمة إن الله كان لطيفا خبيرا","އަދި ތިޔަކަނބަލުންގެ ގެތަކުގައި ﷲގެ އާޔަތް ތަކާއި، ހިކުމަތްގެ ތެރެއިން ކިޔެވޭ ތަކެތި ތިޔަކަނބަލުން ހަނދުމަކުރާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، އޯގާވަންތަކަން ބޮޑު، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެ ކަމުގައިވެއެވެ.","",""],["","","","إن المسلمين والمسلمات والمؤمنين والمؤمنات والقانتين والقانتات والصادقين والصادقات والصابرين والصابرات والخاشعين والخاشعات والمتصدقين والمتصدقات والصائمين والصائمات والحافظين فروجهم والحافظات والذاكرين الله كثيرا والذاكرات أعد الله لهم مغفرة وأجرا عظيما","ހަމަކަށަވަރުން، މުސްލިމު ފިރިހެނުންނާއި، މުސްލިމު އަންހެނުންނާއި، މުއުމިނު ފިރިހެނުންނާއި، މުއުމިނު އަންހެނުންނާއި، ކިޔަމަންތެރި އަޅުވެރި ފިރިހެނުންނާއި، ކިޔަމަންތެރި އަޅުވެރި އަންހެނުންނާއި، ތެދުވެރި ފިރިހެނުންނާއި، ތެދުވެރި އަންހެނުންނާއި، ކެތްތެރި ފިރިހެނުންނާއި، ކެތްތެރި އަންހެނުންނާއި، ބިރުވެތިވާ ފިރިހެނުންނާއި، ބިރުވެތިވާ އަންހެނުންނާއި، ސަދަގާތް ދޭ ފިރިހެނުންނާއި، ސަދަގާތް ދޭ އަންހެނުންނާއި، ރޯދަހިފާ ފިރިހެނުންނާއި، ރޯދަހިފާ އަންހެނުންނާއި، އެއުރެންގެ ފަރުޖުތައް ރައްކާތެރިކުރާ ފިރިހެނުންނާއި، (އެއުރެންގެ ފަރުޖުތައް) ރައްކާތެރިކުރާ އަންހެނުންނާއި، ގިނަގިނައިން ﷲ ހަނދުމަކޮށް ޛިކުރުކުރާ ފިރިހެނުންނާއި، ޛިކުރުކުރާ އަންހެނުންނާއި، އެ އެންމެންނަށްޓަކައި ﷲ ފާފަފުއްސެވުމާއި، ބޮޑުވެގެންވާ ދަރުމަ ތައްޔާރު ކުރެއްވިއެވެ.","",""],["","","","وما كان لمؤمن ولا مؤمنة إذا قضى الله ورسوله أمرا أن يكون لهم الخيرة من أمرهم ومن يعص الله ورسوله فقد ضل ضلالا مبينا","އަދި ﷲއާއި، އެކަލާނގެ ރަސޫލާ ކަމަކަށް ނިޔާކުރައްވައިފިހިނދު، މުއުމިނު ފިރިހެނަކަށްވެސް، އަދި މުއުމިނު އަންހެނަކަށްވެސް، އެއުރެންގެ އެކަމުގައި އެއުރެންނަށް އިޚްތިޔާރު އޮތުމަކީ ނެތްކަމެކެވެ. އަދި ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް އުރެދިއްޖެ މީހާ (ދަންނާށެވެ!) ފަހެ، ފާޅުވެގެންވާ މަގުފުރެދުމަކުން އެމީހަކު ފުރެދިއްޖެކަން ކަށަވަރެވެ.","",""],["","","","وإذ تقول للذي أنعم الله عليه وأنعمت عليه أمسك عليك زوجك واتق الله وتخفي في نفسك ما الله مبديه وتخشى الناس والله أحق أن تخشاه فلما قضى زيد منها وطرا زوجناكها لكي لا يكون على المؤمنين حرج في أزواج أدعيائهم إذا قضوا منهن وطرا وكان أمر الله مفعولا","ﷲ، އެމީހަކަށް (އިސްލާމީ ހިދާޔަތްގެ) ނިއުމަތް ދެއްވައި، އަދި އެމީހެއްގެ މައްޗަށް ކަލޭގެފާނު ހެޔޮކަން ދެއްވާފައިވާ މީހާއަށް، ކަލޭގެފާނު ވިދާޅުވާހިނދު ހަނދުމަ ކުރައްވާށެވެ! ތިބާގެ އަނބިމީހާ ދޫކޮށްނުލައި، ތިބާގެ ގާތުގައި ބައިންދާށެވެ! އަދި ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ﷲ ފާޅުކުރައްވާނޭ ކަންތައް ކަލޭގެފާނުގެ ހިތްޕުޅުގައި ވަންހަނާ ކުރައްވަމުއެވެ. އަދި މީސްތަކުންދެކެ ކަލޭގެފާނު ބިރުފުޅު ގަނެތެވެ. އަދި ކަލޭގެފާނު ބިރުފުޅުގަތުން ހައްގު ކަންބޮޑީ ﷲ ދެކެއެވެ. ފަހެ، ޒައިދު، އެކަމަނާގެ ކިބައިން ބޭނުމެއް ފުއްދައިފިހިނދު (އެބަހީ: އަނތްބެއްގެ ގޮތުގައި ބޭނުންކުރުމަށްފަހު ވަރިކޮށް އިއްދަ ހަމަވުމުން) ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނާ އެކަމަނާއާ ކާވެނިކޮށްދެއްވީމެވެ. އެއީ މުއުމިނުންނަށް، އެއުރެން ދަރިންކަމަށް ހަދައިގެންއުޅޭ މީހުންގެ އަނބިންގެ ކިބައިން، އެއުރެންގެ ބޭނުމެއް ފުއްދައި (ވަރިކޮށް) ފިހިނދު، އެއުރެންނާ ކާވެނި ކުރުމުގައި ފާފައެއް ނެތްކަން އެންގެވުމަށްޓަކައެވެ. އަދި ﷲގެ އަމުރުފުޅަކީ، ހިނގަނިވި ކަމެއްކަމުގައި ވެއެވެ.","",""],["","","","ما كان على النبي من حرج فيما فرض الله له سنة الله في الذين خلوا من قبل وكان أمر الله قدرا مقدورا","ﷲ، ނަބިއްޔާއަށް ހުއްދަކޮށްދެއްވި ގޮތާމެދު، އެއްވެސް ކުށެއް ފާފަޔެއް އެ ނަބިއްޔާއަކަށް ނުވެއެވެ. (އެއީ) އިސްވެދިޔަ ނަބިއްޔުންގެ ތެރޭގައިވެސް ﷲ، ކަން ހިންގެވިގޮތެވެ. އަދި ﷲގެ އަމުރުފުޅު އެއީ، ކަނޑައެޅި ނިޔާކުރައްވާފައިވާ ނިޔާއެއް ކަމުގައި ވެއެވެ.","",""],["","","","الذين يبلغون رسالات الله ويخشونه ولا يخشون أحدا إلا الله وكفى بالله حسيبا","އެއުރެންނީ (އެބަހީ: ރަސޫލުންނީ) ﷲގެ އެންގެވުންތައް މީސްތަކުންނަށް އަންގަވާ ބަޔެކެވެ. އަދި އެބޭކަލުން އެކަލާނގެ ދެކެ ބިރުވެތިވެތެވެ. އަދި އެބޭކަލުންނީ ﷲ ފިޔަވައި އެހެންފަރާތަކަށް ބިރުވެތިވާ ބަޔެއްނޫނެވެ. އަދި ހިސާބު ބައްލަވަނިވި ކަލަކު ކަމުގައި ﷲ ފުދިވޮޑިގެންވެއެވެ.","",""],["","","","ما كان محمد أبا أحد من رجالكم ولكن رسول الله وخاتم النبيين وكان الله بكل شيء عليما","ތިޔަބައިމީހުންގެ ބޮޑެތި ފިރިހެނުންގެ ތެރެއިން އެކެއްގެވެސް ބަފައިކަލަކު ކަމުގައި މުޙައްމަދުގެފާނު ނުވެތެވެ. އެހެނެއްކަމަކު، (އެކަލޭގެފާނީ) ﷲގެ ރަސޫލާއެވެ. އަދި ނަބީކަން ޚަތިމުކުރެއްވި ކަލޭގެފާނުވެސްމެއެވެ. އަދި ކޮންމެ ކަމެއްމެ މޮޅަށް ދެނެވޮޑިގެންވާ ކަލަކުކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","يا أيها الذين آمنوا اذكروا الله ذكرا كثيرا","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ގިނަވެގެންވާ ހަނދުމަކުޅައުމަކުން ﷲ ހަނދުމަކުރާށެވެ!","",""],["","","","وسبحوه بكرة وأصيلا","އަދި ހެނދުނާއި، ހަވީރު އެކަލާނގެއަށް ތަސްބީހަ ކިޔައި އުޅޭށެވެ!","",""],["","","","هو الذي يصلي عليكم وملائكته ليخرجكم من الظلمات إلى النور وكان بالمؤمنين رحيما","އެކަލާނގެއީ، ތިޔަބައިމީހުންގެ މައްޗަށް ރަހުމަތް ލައްވާ ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެ މަލާއިކަތުން ތިޔަބައިމީހުންގެ ފާފަފުއްސެވުމަށްއެދި ދުއާކުރައްވަތެވެ. އެއީ ކާފިރުކަމުގެ އަނދިރިކަމުން އީމާންކަމުގެ އަލިކަމުގެ ތެރެޔަށް އެކަލާނގެ ތިޔަބައިމީހުން ނެރުއްވުމަށްޓަކައެވެ. އަދި މުއުމިނުންނަށް ރަޙީމްވަންތަ ކަލަކު ކަމުގައި އެކަލާނގެ ވޮޑިގެންވެއެވެ.","",""],["","","","تحيتهم يوم يلقونه سلام وأعد لهم أجرا كريما","އެކަލާނގެއާ އެއުރެން ބައްދަލުވާދުވަހު (އެބަހީ: ގިޔާމަތް ދުވަހު) އެއުރެންގެ ތަޙިއްޔަތަކީ ސަލާމެވެ. އަދި ދީލަތިވެގެންވާ ދަރުމަ (އެބަހީ: ސުވަރުގެ) އެއުރެންނަށްޓަކައި އެކަލާނގެ ތައްޔާރު ކުރެއްވިއެވެ.","",""],["","","","يا أيها النبي إنا أرسلناك شاهدا ومبشرا ونذيرا","އޭ ނަބިއްޔާއެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނު ފޮނުއްވީ ހެކިވަނިވި ބޭކަލަކު ކަމުގައްޔާއި (މުއުމިނުންނަށް) އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު ކަމުގައްޔާއި (ކާފިރުންނަށް) ބިރުވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު ކަމުގައެވެ.","",""],["","","","وداعيا إلى الله بإذنه وسراجا منيرا","އަދި ﷲގެ ދީނަށް، އެކަލާނގެ އަމުރު ފުޅާއެކު (މީސްތަކުންނަށް) ގޮވައިލައްވާ ބޭކަލަކު ކަމުގައްޔާއި (އެއުރެންގެ މަގަށް) އަލިކުރާ ވޮށެއްފަދަ ބޭކަލަކު ކަމުގައެވެ.","",""],["","","","وبشر المؤمنين بأن لهم من الله فضلا كبيرا","އަދި ހަމަކަށަވަރުން، ﷲގެ ހަޒުރަތުން ބޮޑުވެގެންވާ ފަޟްލު ވަންތަކަން އެއުރެންނަށް ހުރިކަމަށް މުއުމިނުންނަށް ކަލޭގެފާނު އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާށެވެ!","",""],["","","","ولا تطع الكافرين والمنافقين ودع أذاهم وتوكل على الله وكفى بالله وكيلا","އަދި ކާފިރްނާއި، މުނާފިގުންނަށް ކަލޭގެފާނު ކިޔަމަންވެވަޑައިނުގަންނަވާށެވެ! އަދި އެއުރެންގެ އުނދަގޫތައް (ފަރުވާލެއް ނުބަހައްޓަވައި) ދޫކޮށްލައްވާށެވެ! އަދި ﷲއަށް ވަކީލުކުރައްވާށެވެ! އަދި ވަކީލަކު ކަމުގައި ﷲ ފުދެތެވެ.","",""],["","","","يا أيها الذين آمنوا إذا نكحتم المؤمنات ثم طلقتموهن من قبل أن تمسوهن فما لكم عليهن من عدة تعتدونها فمتعوهن وسرحوهن سراحا جميلا","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން، މުއުމިނު އަންހެނުންނާ ކާވެނިކޮށް، ދެން އެކަނބަލުންގެ ގާތުގައި ރޭކުރުމުގެ ކުރިން، ތިޔަބައިމީހުން އެކަނބަލުން ވަރިކޮށްފިނަމަ، އިއްދަގެ ގޮތުން ތިޔަބައިމީހުން ގުނާނެ ދުވަސްތަކެއް އެކަނބަލުންގެ މައްޗަށް ތިޔަބައިމީހުންނަކަށް ނުވެތެވެ. ފަހެ، އެކަނބަލުންގެ ހިތްހަމަޖެއްސުމުގެގޮތުން ކޮންމެވެސް އެއްޗެއް (އެބަހީ: މުތުއާއެއް) ތިޔަބައިމީހުން އެކަނބަލުންނަށް ދޭށެވެ! އަދި ތިޔަބައިމީހުން ރީތިވެގެންވާ ދޫކޮށްލުމަކުން އެކަނބަލުން ދޫކޮށްލާށެވެ! (ނޯޓު: މިއީ ރަނެއް ކަނޑައަޅާފައިނުވާނަމަ، އޮންނަގޮތެވެ. ރަނެއް ކަނޑައަޅާފައި އޮތްނަމަ، އޭގެ ދެބައިކުޅައެއްބައި ދޭންޖެހޭނެއެވެ.)","",""],["","","","يا أيها النبي إنا أحللنا لك أزواجك اللاتي آتيت أجورهن وما ملكت يمينك مما أفاء الله عليك وبنات عمك وبنات عماتك وبنات خالك وبنات خالاتك اللاتي هاجرن معك وامرأة مؤمنة إن وهبت نفسها للنبي إن أراد النبي أن يستنكحها خالصة لك من دون المؤمنين قد علمنا ما فرضنا عليهم في أزواجهم وما ملكت أيمانهم لكيلا يكون عليك حرج وكان الله غفورا رحيما","އޭ ނަބިއްޔާއެވެ! ކަލޭގެފާނު އެކަނބަލުންގެ ރަން ދެއްވާފައިވާ އަނބިއަނބިކަނބަލުންނާއި، ހަނގުރާމައިގެ ޣަނީމާގެ ގޮތުގައި ކަލޭގެފާނަށް ﷲ ދެއްވި ތަކެތީގެ ތެރެއިން، ކަލޭގެފާނަށް މިލްކުވެއްޖެ އަޅު އަންހެނުންނާއި، އެކަނބަލުން ކަލޭގެފާނާއެކު ހިޖުރަކުރެއްވި ކަލޭގެފާނުގެ ބަފައިފުށުގެ ބޮޑުބޭބެއިންގެ އަންހެން ދަރިންނާއި، ބަފައިފުށުގެ ބޮޑުދައިތައިންގެ އަންހެން ދަރިންނާއި، ކަލޭގެފާނުގެ މައިފުށުގެ ބޮޑުބޭބެއިންގެ އަންހެން ދަރިންނާއި، މައިފުށުގެ ބޮޑުދައިތައިންގެ އަންހެން ދަރިން، ހަމަކަށަވަރުން، ތިމަން ރަސްކަލާނގެ ކަލޭގެފާނަށް ހުއްދަކޮށް ހަލާލުކުރެއްވީމެވެ. އަދި މުއުމިނު އަންހެނަކު އެމީހެއްގެ އަމިއްލަ ނަފްސު ނަބިއްޔާއަށް ހިބަ ކޮށްދީ، އަދި ނަބިއްޔާ އެމީހަކާ ކާވެނި ކުރެއްވުމަށް ގަސްދުކުރައްވައިފިނަމަ، އެމީހަކާ ކާވެނި ކުރެއްވުންވެސް ހުއްދަ ކުރެއްވީމެވެ. އެހެން މުއުމިނުން ފިޔަވައި، އެމީހަކު ކަލޭގެފާނަށް ހާއްސަ ވެގެންވާ ގޮތުގައެވެ. އެއުރެންގެ އަނބިންނާ މެދުގައްޔާއި، އެއުރެންނަށް މިލްކުވެގެންވާ އަޅުންނާމެދު، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ކަނޑައަޅުއްވާފައިވާގޮތް، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގެންވަމެވެ. އެއީ ކަލޭގެފާނުގެ މައްޗަށް ދަތިކަމެއް ނުވުމަށްޓަކައެވެ. ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ. (ނޯޓު: އަންހެނަކު އެމީހެއްގެ ނަފްސު ހިބަކޮށްދީފިނަމަ، ރަނަކާ ނުލައި ކާވެނިކުރުން ހުއްދަވެގެންވީ ހަމައެކަނި ކީރިތި ރަސޫލާއަށެވެ.)","",""],["","","","ترجي من تشاء منهن وتؤوي إليك من تشاء ومن ابتغيت ممن عزلت فلا جناح عليك ذلك أدنى أن تقر أعينهن ولا يحزن ويرضين بما آتيتهن كلهن والله يعلم ما في قلوبكم وكان الله عليما حليما","އެކަނބަލުންގެ ތެރެއިން ކަލޭގެފާނު އެދިވަޑައިގަންނަވާ މީހަކު (ރޭކުރެއްވުމުގައި) ފަސްކުރެއްވިޔަސް، އަދި ކަލޭގެފާނު އެދިވަޑައިގަންނަވާ މީހަކު، ކަލޭގެފާނުގެ އަރިހަށް ގެންނެވިޔަސް، އަދި ކަލޭގެފާނު ދުރުކުރައްވާފައިވާ މީހުންގެ ތެރެއިން ކަލޭގެފާނު ބޭނުންފުޅު މީހަކު (އަލުން) ގެންނެވިޔަސް އެކަމުން ކަލޭގެފާނުގެ މައްޗަކަށް ކުށެއް ނެތެވެ. އެއީ އެކަނބަލުންގެ ލޯތަކަށް ފިނިކަން ޙާޞިލު ވުމަށާއި، އެކަނބަލުން މޮޅިނުވުމަށާއި، ކަލޭގެފާނު އެކަނބަލުންނަށް ދެއްކެވި ގޮތާމެދު، އެކަނބަލުން އެންމެން ރުހުމަށް އެގޮތް ގާތްކަން ބޮޑީއެވެ. ތިޔަބައިމީހުންގެ ހިތްތަކުގައިވާ އެއްޗެއް، ﷲ ދެނެވޮޑިގެންވެތެވެ. ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ހަލީމްވަންތަ ރަސްކަލާނގެ ކަމުގައި ވޮޑިގެންވެއެވެ.","",""],["","","","لا يحل لك النساء من بعد ولا أن تبدل بهن من أزواج ولو أعجبك حسنهن إلا ما ملكت يمينك وكان الله على كل شيء رقيبا","މީގެފަހުން، ކަލޭގެފާނަކަށް އިތުރަށް އަންހެނުން ހުއްދަވެގެނެއް ނުވެތެވެ. އަދި އެކަނބަލުންގެ ރީތިކަން، ކަލޭގެފާނު އަޖާއިބު ފުޅުވާ ދަރަޖައަށް ހުއްޓަސް، ކަލޭގެފާނުގެ އަނބިއަނބިކަނބަލުންގެ ތެރެއިން ބަޔެއްގެ ބަދަލުގައި އެހެންބަޔަކާ ކާވެނިކުރެއްވުންވެސް ކަލޭގެފާނަކަށް ހުއްދަވެގެނެއް ނުވެތެވެ. ކަލޭގެފާނަށް މަލަކަ ވެގެންވާ އަޅު އަންހެނުން މެނުވީއެވެ. ކޮންމެ ކަމެއްގެ މައްޗަށް ބައްލަވާވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","يا أيها الذين آمنوا لا تدخلوا بيوت النبي إلا أن يؤذن لكم إلى طعام غير ناظرين إناه ولكن إذا دعيتم فادخلوا فإذا طعمتم فانتشروا ولا مستأنسين لحديث إن ذلكم كان يؤذي النبي فيستحيي منكم والله لا يستحيي من الحق وإذا سألتموهن متاعا فاسألوهن من وراء حجاب ذلكم أطهر لقلوبكم وقلوبهن وما كان لكم أن تؤذوا رسول الله ولا أن تنكحوا أزواجه من بعده أبدا إن ذلكم كان عند الله عظيما","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންނަށް ކެއުމަކަށް އިޒުނަ ދެއްވުމުން މެނުވީ، އަދި އެ ކެއުން ތައްޔާރުވެއްޖައުމަށް ދާނދެން، އިންތިޒާރުކުރުމަކާ ނުލައި، ނަބިއްޔާގެ ގޭގެއަށް ތިޔަބައިމީހުން ނުވަންނާށެވެ! އެހެނެއްކަމަކު ތިޔަބައިމީހުންނަށް ގޮވައިލައްވައިފިނަމަ، ފަހެ، ތިޔަބައިމީހުން ވަންނާށެވެ! އަދި ތިޔަބައިމީހުން ކައި އަވަދިވެއްޖެނަމަ، ފަހެ، ތިޔަބައިމީހުން ދާށެވެ! އަދި ވާހަކަ ދެއްކުމުން މުނިފޫހިފިލުވާ ގޮތުގައި ތިޔަބައިމީހުން ނުތިބޭށެވެ! (އެހެނީ) ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ އެކަމަކީ، ނަބިއްޔާއަށް އުނދަގޫދޭ ކަމެއްކަމުގައިވެތެވެ. އަދި އެކަމުގެ ސަބަބުން ތިޔަބައިމީހުންދެކެ އެކަލޭގެފާނު ލަދުފުޅުގަނެތެވެ. ހައްގު ގޮތް ބަޔާންކުރެއްވުމަށް ﷲ ލަދުވެތިވެވޮޑިއެއްނުގަންނަވަތެވެ. އަދި އެކަނބަލުން (އެބަހީ: ނަބިއްޔާގެ އަނބިއަނބިކަނބަލުން) ގެ ކިބައިން ތިޔަބައިމީހުން އެއްޗަކަށް އެދޭނަމަ، ފަހެ، ފަރުދާއެއްގެ އަނެއްފަރާތުން ތިޔަބައިމީހުން އެކަނބަލުންނާ ސުވާލުކުރާށެވެ! ތިޔަބައިމީހުންގެ ހިތްތަކަށާއި، އެކަނބަލުންގެ ހިތްޕުޅުތަކަށް އެންމެ ތާހިރު ކަންބޮޑީ އެގޮތެވެ. ﷲގެ ރަސޫލާއަށް ތިޔަބައިމީހުން އުނދަގޫ ކުރުމެއް، އަދި އެކަލޭގެފާނަށްފަހު ދުވަހަކުވެސް އެކަލޭގެފާނުގެ އަނބިއަނބިކަނބަލުންނާ ކާވެނިކުރުމެއް ތިޔަބައިމީހުންނަކަށް ހުއްދަވެގެނެއް ނުވެތެވެ. ހަމަކަށަވަރުން، އެކަމަކީ، ﷲގެ ހަޒުރަތުގައި ބޮޑުވެގެންވާ ކަމެއްކަމުގައި (އެބަހީ: ފާފައެއްކަމުގައި) ވެއެވެ.","",""],["","","","إن تبدوا شيئا أو تخفوه فإن الله كان بكل شيء عليما","ތިޔަބައިމީހުން ކަމެއް ފާޅުކުޅަޔަސް، ނުވަތަ އެކަމެއް ވަންހަނާކުޅަޔަސް ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ކަލާނގެ ކަމުގައި ވޮޑިގެންވެއެވެ.","",""],["","","","لا جناح عليهن في آبائهن ولا أبنائهن ولا إخوانهن ولا أبناء إخوانهن ولا أبناء أخواتهن ولا نسائهن ولا ما ملكت أيمانهن واتقين الله إن الله كان على كل شيء شهيدا","އެކަނބަލުންގެ (އެބަހީ: ރަސޫލާގެ އަނބިއަނބިކަނބަލުންގެ) ބަފައިންނާ މެދުގައްޔާއި، އެކަނބަލުންގެ ފިރިހެން ދަރިންނާ މެދުގައްޔާއި، އެކަނބަލުންގެ އަޚުންނާ މެދުގައްޔާއި، އެކަނބަލުންގެ އަޚުންގެ ފިރިހެން ދަރީންނާ މެދުގައްޔާއި، އެކަނބަލުންގެ އުޚްތުންގެ ފިރިހެން ދަރިންނާ މެދުގައްޔާއި، މުއުމިނު އަންހެނުންނާ މެދުގައްޔާއި، އެކަނބަލުންނަށް މަލަކަ ވެގެންވާ އަޅުންނާ މެދުގައި (ފަރުދާ ނުކުރެއްވިޔަސް) އެކަނބަލުންގެ މައްޗަކަށް ކުށެއް ފާފައެއް ނެތެވެ. އަދި ތިޔަކަނބަލުން ﷲއަށް ތަގުވާވެރިވާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެ ކަމެއްގެ މައްޗަށް މޮޅަށް ހެކިވެވޮޑިގެންވާ ރަސްކަލާނގެ ކަމުގައި ވޮޑިގެންވެއެވެ.","",""],["","","","إن الله وملائكته يصلون على النبي يا أيها الذين آمنوا صلوا عليه وسلموا تسليما","ހަމަކަށަވަރުން، ﷲއާއި، އެކަލާނގެ މަލާއިކަތުން ނަބިއްޔާގެ މައްޗަށް ޞަލަވާތް ލައްވަތެވެ. އޭ އީމާން ވެއްޖެ މީސްކަތުންނޭވެ! ތިޔަބައިމީހުން އެކަލޭގެފާނުގެ މައްޗަށް ޞަލަވާތް ލެއްވުން އެދި ދުއާކުރާށެވެ! އަދި އެކަލޭގެފާނުގެ މައްޗަށް ސަލާމް ލެއްވުންއެދި ތިޔަބައިމީހުން ގިނަގިނައިން ދުއާކުރާށެވެ!","",""],["","","","إن الذين يؤذون الله ورسوله لعنهم الله في الدنيا والآخرة وأعد لهم عذابا مهينا","ހަމަކަށަވަރުން، ﷲއާއި، އެކަލާނގެ ރަސޫލާއަށް އުނދަގޫކުރާ (އެބަހީ: ދޮގުކޮށް ކާފިރުވާ) މީހުން (ދަންނާށެވެ!) ﷲ، އެއުރެންނަށް ދުނިޔެއާއި، އާޚިރަތުގައި ލައުނަތް ލެއްވިއެވެ. އަދި އެކަލާނގެ އިހާނަތްތެރި އަޒާބެއުރެންނަށްޓަކައި ތައްޔާރުކުރެއްވިއެވެ.","",""],["","","","والذين يؤذون المؤمنين والمؤمنات بغير ما اكتسبوا فقد احتملوا بهتانا وإثما مبينا","އަދި އެއުރެން ހޯދައިގަތް ކުށަކާނުލައި މުއުމިނު ފިރިހެނުންނަށާއި، މުއުމިނު އަންހެނުންނަށް އުނދަގޫކުރާ މީހުން (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އެއުރެންނީ ބުހުތާނު ދޮގަކާއި، ފާޅުވެގެންވާ ފާފައެއް ލިބިގެންފި ބަޔެކެވެ.","",""],["","","","يا أيها النبي قل لأزواجك وبناتك ونساء المؤمنين يدنين عليهن من جلابيبهن ذلك أدنى أن يعرفن فلا يؤذين وكان الله غفورا رحيما","އޭ ނަބިއްޔާއެވެ! ކަލޭގެފާނުގެ އަނބިއަނބިކަނބަލުންނާއި، ކަލޭގެފާނުގެ ދަރިދަރިކަނބަލުންނާއި، މުއުމިނުންގެ އަންހެނުން، އެކަނބަލުންގެ ފޭރާންތަކުން ނިވައިވެތިބުމަށް ކަލޭގެފާނު އެކަނބަލުންނަށް ވިދާޅުވާށެވެ! އެކަނބަލުން އެނގިގެން ވުމަށާއި، އެކަނބަލުންނަށް އުނދަގޫ ނުލިބުމަށް އެގޮތް މާގާތްކަން ބޮޑެވެ. ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެ ކަމުގައި ވޮޑިގެންވެއެވެ.","",""],["","","","لئن لم ينته المنافقون والذين في قلوبهم مرض والمرجفون في المدينة لنغرينك بهم ثم لا يجاورونك فيها إلا قليلا","ހަމަކަށަވަރުން، މުނާފިގްނާއި އެއުރެންގެ ހިތްތަކުގައި ބަލިމަޑުކަމެއް އުފެދިފައިވާ މީހުންނާއި، މުއުމިނުން ބިރުގެންނެވުމަށް އަލްމަދީނާގައި ދޮގު ވާހަކަތައް ފަތުރައި، ފިތުނައުފައްދާ މީހުން އެކަން ހުއްޓައިނުލިނަމަ، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް ކަލޭގެފާނު ފާކުރައްވައި ފޮނުއްވައިފާހުށީމެވެ. ދެންފަހެ ކަލޭގެފާނުގެ އަވަށްޓެރިންގެ ގޮތުގައި ވަރަށް ކުރު މުއްދަތަކަށް މެނުވީ އެއުރެން އެރަށުގައި ނުތިބޭނެތެވެ.","",""],["","","","ملعونين أينما ثقفوا أخذوا وقتلوا تقتيلا","އެއުރެންނަށް ލައުނަތް ލައްވާފައިވާ ޙާލު ގައެވެ. (އަދި) އެއުރެން ފެނުނު ކޮންމެ ތަނަކުން ހިފެވި، ބިރުވެރި ގަތުލުކުރުމަކުން، އެއުރެން ގަތުލުކުރެވޭހުށްޓެވެ.","",""],["","","","سنة الله في الذين خلوا من قبل ولن تجد لسنة الله تبديلا","(އެއީ) އިސްވެދިޔަ މީހުންނާމެދު، ﷲ، ކަންހިންގެވިގޮތެވެ. އަދި ﷲ ކަންހިންގަވާގޮތަށް ބަދަލެއް އަންނާތީ ކަލޭގެފާނަކަށް ފެނިވަޑައެއް ނުގަންނަވާނެތެވެ.","",""],["","","","يسألك الناس عن الساعة قل إنما علمها عند الله وما يدريك لعل الساعة تكون قريبا","ގިޔާމަތް ވުމުގެ ވަގުތާމެދު މީސްތަކުން ކަލޭގެފާނާ ސުވާލުކުރެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަމުގެ އިލްމު ވާކަން ކަށަވަރީ، ﷲގެ ހަޒުރަތު ގައެވެ. އަދި ކަލޭގެފާނަށް އެކަން އަންގައިދެނީ ކޮންއެއްޗެއްތޯއެވެ؟ ގިޔާމަތް ވުމުގެ ވަގުތު ވަރަށް ގާތްވެފައިވެސް އޮވެދާނެތެވެ.","",""],["","","","إن الله لعن الكافرين وأعد لهم سعيرا","ހަމަކަށަވަރުން، ﷲ، ކާފިރުންނަށް ލައުނަތް ލެއްވިއެވެ. އަދި އެއުރެންނަށްޓަކައި އަނދައަނދާހުންނަ ނަރަކަ ތައްޔާރު ކުރެއްވިއެވެ.","",""],["","","","خالدين فيها أبدا لا يجدون وليا ولا نصيرا","އެތާނގައި އެއުރެންނަށް އަބަދަށް ދެމިތިބެނިވި ގޮތުގައެވެ. އެހީތެރިޔަކު ނުވަތަ ނަސްރު ދޭނޭ މީހަކުވެސް އެއުރެން ނުދެކޭނެތެވެ.","",""],["","","","يوم تقلب وجوههم في النار يقولون يا ليتنا أطعنا الله وأطعنا الرسولا","އެއުރެންގެ މޫނުތައް، ނަރަކައިގައި ފުރޮޅަފުރޮޅައިތިބޭ ދުވަހެވެ. އެއުރެން ބުނާނެތެވެ. ތިމަންމެން ﷲއަށް ކިޔަމަންވެ، އަދި (އެކަލާނގެ) ރަސޫލާއަށް ކިޔަމަންވީނަމަ ކިހާރަނގަޅު ހެއްޔެވެ!","",""],["","","","وقالوا ربنا إنا أطعنا سادتنا وكبراءنا فأضلونا السبيلا","އަދި އެއުރެން ބުނާނެތެވެ. އަޅަމެންގެ ވެރި ރަސްކަލާކޮ! ހަމަކަށަވަރުން، އަޅަމެންގެ ސާހިބުންނަށާއި، އަޅަމެންގެ ބޮޑުންނަށް، އަޅަމެން ކިޔަމަންވީމުއެވެ. ފަހެ، އެއުރެން އަޅަމެން މަގުފުރެއްދީއެވެ.","",""],["","","","ربنا آتهم ضعفين من العذاب والعنهم لعنا كبيرا","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޒާބުގެ ތެރެއިން ދެގުނަ، އެއުރެންނަށް ދެއްވާނދޭވެ! އަދި ބޮޑުވެގެންވާ ލައުނަތް ލެއްވުމަކުން، އެއުރެންނަށް ލައުނަތް ލައްވާނދޭވެ!","",""],["","","","يا أيها الذين آمنوا لا تكونوا كالذين آذوا موسى فبرأه الله مما قالوا وكان عند الله وجيها","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! މޫސާގެފާނަށް އުނދަގޫކޮށް އުޅުނު މީހުން ފަދައިން ތިޔަބައިމީހުން ނުވާށެވެ! ފަހެ، އެއުރެން އެކަލޭގެފާނާމެދު ދެއްކި ވާހަކައިން، ﷲ، އެކަލޭގެފާނު ބަރީއަކުރެއްވިއެވެ. އަދި ﷲގެ ހަޒުރަތުގައި އެކަލޭގެފާނު، ގަދަރު އުފުލިގެންވާ ބޭކަލަކު ކަމުގައި ވިއެވެ.","",""],["","","","يا أيها الذين آمنوا اتقوا الله وقولوا قولا سديدا","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ސީދާވެގެންވާ ބުނުމަކުން ތިޔަބައިމީހުން ބަސްބުނާށެވެ!","",""],["","","","يصلح لكم أعمالكم ويغفر لكم ذنوبكم ومن يطع الله ورسوله فقد فاز فوزا عظيما","(އޭރުން) ތިޔަބައިމީހުންނަށްޓަކައި، ތިޔަބައިމީހުންގެ ޢަމަލުތައް އެކަލާނގެ އިސްލާހު ކޮށްދެއްވާނެތެވެ. އަދި ތިޔަބައިމީހުންނަށްޓަކައި، އެކަލާނގެ ތިޔަބައިމީހުންގެ ފާފަތައް ފުއްސަވައިދެއްވާނެތެވެ. ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް ކިޔަމަންވާ މީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ބޮޑުވެގެންވާ ނަސީބު ލިބުމަކުން އެމީހާއަށް ނަސީބު ލިބިއްޖެއެވެ.","",""],["","","","إنا عرضنا الأمانة على السماوات والأرض والجبال فأبين أن يحملنها وأشفقن منها وحملها الإنسان إنه كان ظلوما جهولا","ހަމަކަށަވަރުން، އުޑުތަކަށާއި، ބިމަށާއި، ފަރުބަދަތަކަށް ތިމަންރަސްކަލާނގެ އަމާނަތް (އެބަހީ: ތަކުލީފުތައް) ހުށަހެޅުއްވީމެވެ. ފަހެ، އެ ތަކެތި އެކަން އުފުލުމުން އެއްކިބާވެ މަނާވެގަތެވެ. އަދި އެކަމާމެދު އެތަކެތި ބިރުވެތިވިއެވެ. އަދި އިންސާނާއެ އަމާނަތް އުފުލިއެވެ. ހަމަކަށަވަރުން، އެ އިންސާނު އާވީ އަނިޔާވެރި، ތަންދޮރު ނުދަންނަ މީހަކު ކަމުގައެވެ.","",""],["","","","ليعذب الله المنافقين والمنافقات والمشركين والمشركات ويتوب الله على المؤمنين والمؤمنات وكان الله غفورا رحيما","(އެއީ) މުނާފިގު ފިރިހެނުންނާއި، މުނާފިގު އަންހެނުންނާއި، ޝަރީކުކުރާ ފިރިހެނުންނާއި، ޝަރީކުކުރާ އަންހެނުންނަށް ﷲ އަޒާބު ދެއްވުމަށްޓަކައެވެ. އަދި މުއުމިނު ފިރިހެނުންނާއި، މުއުމިނު އަންހެނުންނަށް ﷲ ތައުބާ ލެއްވުމަށްޓަކައެވެ. ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެ ކަމުގައި ވޮޑިގެންވެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم الحمد لله الذي له ما في السماوات وما في الأرض وله الحمد في الآخرة وهو الحكيم الخبير","ހަމްދު ހުރީ ﷲއަށެވެ. އެކަލާނގެއީ، އުޑުތަކާއި، ބިމުގައިވާހާ އެއްޗަކާއި، ކަމެއް، އެކަލާނގެއަށް މިލްކުވެގެންވާ ރަސްކަލާނގެއެވެ. އަދި އާޚިރަތް ދުވަހުންވެސް ހަމްދު ހުރީ އެކަލާނގެއަށެވެ. އަދި އެކަލާނގެއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","يعلم ما يلج في الأرض وما يخرج منها وما ينزل من السماء وما يعرج فيها وهو الرحيم الغفور","ބިމުގެ ތެރެޔަށް ވަދެގެންދާހާ ތަކެއްޗާއި، އެ ބިމުގެ ތެރެއިން ނިކުންނަހާ ތަކެއްޗާއި، އުޑުން ފައިބާހާ އެއްޗަކާއި، އެ އުޑަށް އަރައިގެންދާހާ އެއްޗެއް އެކަލާނގެ ދެނެވޮޑިގެންވެއެވެ. އަދި އެކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وقال الذين كفروا لا تأتينا الساعة قل بلى وربي لتأتينكم عالم الغيب لا يعزب عنه مثقال ذرة في السماوات ولا في الأرض ولا أصغر من ذلك ولا أكبر إلا في كتاب مبين","ކާފިރުވި މީހުން ބުނޫއެވެ. ގިޔާމަތް ވުމުގެ ވަގުތު ތިމަންމެންނާ ހަމަޔަކަށް ނާންނާނެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އަދި ކިއެއްތަ! އެހެންނަކުންނޫނެވެ. ތިމަންގެ ވެރިރަސްކަލާނގެ ގަންދެއްވަމެވެ. އެވަގުތު (އެބަހީ: ގިޔާމަތް ވުމުގެ ވަގުތު) ތިޔަބައިމީހުންނާ ހަމަޔަށް އަންނާނެކަން ކަށަވަރެވެ. އެކަލާނގެއީ، ޣައިބު ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އުޑުތަކާއި، ބިމުގައިވާ ޒައްރެއްގެ މިންވަރުވެސް، އަދި އެއަށްވުރެ ކުޑަޔަސް އަދި އެއަށްވުރެ ބޮޑަސް، އެކަލާނގެއަށް ވަންހަނާވެގެންނެއް ނުވެތެވެ. ބަޔާން ވެގެންވާ ފޮތެއްގައި އެތަކެތި ލިޔުއްވާފައިވާ ކަމުގައި މެނުވީ ނުވެތެވެ.","",""],["","","","ليجزي الذين آمنوا وعملوا الصالحات أولئك لهم مغفرة ورزق كريم","(އެއީ) އީމާންވެ ސާލިހު ޢަމަލުތައްކުޅަ މީހުންނަށް (ހެޔޮ) ޖަޒާ ދެއްވުމަށްޓަކައެވެ. އެއުރެންނަށް ފާފަފުއްސެވުމާއި، ދީލަތިވެގެންވާ ރިޒްގު ހުށްޓެވެ.","",""],["","","","والذين سعوا في آياتنا معاجزين أولئك لهم عذاب من رجز أليم","ތިމަންރަސްކަލާނގެ (ބާވައިލެއްވި) އާޔަތް ތަކާ ދެކޮޅުހަދަމުން ހިނގިމީހުން (ދަންނާށެވެ!) ވޭންދެވިނި އެންމެގަދަ އަޒާބުން އެއުރެންނަށް އަޒާބު ހުށްޓެވެ.","",""],["","","","ويرى الذين أوتوا العلم الذي أنزل إليك من ربك هو الحق ويهدي إلى صراط العزيز الحميد","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ކަލޭގެފާނަށް ބާވައިލެއްވި ފޮތް އެއީ ހައްގު ބަސްފުޅު ކަމުގައި، އެއުރެންނަށް އިލްމު ލިބިގެންވާ މީހުން ދެކޭނެތެވެ. އަދި އެ ފޮތް މަގުދައްކަނީ، ޢަޒީޒުވަންތަ، ހަމްދު ލިބިވޮޑިގެންވާ ރަސްކަލާނގެ މަގަށެވެ.","",""],["","","","وقال الذين كفروا هل ندلكم على رجل ينبئكم إذا مزقتم كل ممزق إنكم لفي خلق جديد","ކާފިރު ވިމީހުން ބުނޫއެވެ. ތިޔަބައިމީހުން މަރުވެ، ކުދިކުދި އެތިކޮޅުތަކަކަށް ވަކިވެދާހިނދު، އަލުން އާ އުފެއްދުމެއްގައި ހަމަކަށަވަރުން، ތިޔަބައިމީހުން އުފެދިގެންދާނެކަމަށް ތިޔަބައިމީހުންގެ ގާތުގައި ބުނެ، ޚަބަރު ދޭމީހަކު ތިޔަބައިމީހުންނަށް ތިމަންމެން ދައްކަންހެއްޔެވެ؟","",""],["","","","أفترى على الله كذبا أم به جنة بل الذين لا يؤمنون بالآخرة في العذاب والضلال البعيد","އޭނާ ﷲއާމެދު ހަދައިގެން ދޮގެއް ބުނީހެއްޔެވެ؟ ނުވަތަ އޭނާގެ ކިބައިގައި މޮޔަކަމެއް ހުންނަނީ ހެއްޔެވެ؟ އަދި ކިއެއްތަ! އާޚިރަތަށް އީމާން ނުވާ މީހުން (އާޚިރަތުގައި) ވަނީ އަޒާބު ގައެވެ. އަދި (ދުނިޔޭގައި އެއުރެންވަނީ) ދުރުވެގެންވާ މަގުފުރެދުމެއްގައެވެ.","",""],["","","","أفلم يروا إلى ما بين أيديهم وما خلفهم من السماء والأرض إن نشأ نخسف بهم الأرض أو نسقط عليهم كسفا من السماء إن في ذلك لآية لكل عبد منيب","އަދި އުޑާއި، ބިމުން އެއުރެންގެ ކުރިމަތީގައިވާތަނާއި، އެއުރެންގެ ފުރަގަހުގައިވާތަން، އެއުރެންނަށް ނުފެންނަނީ ހެއްޔެވެ؟ ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާނަމަ، ބިންގަނޑު އެއުރެންނާއިގެން ގަންބަވައިގެންފާހުށީމެވެ. ނުވަތަ އުޑުން ތަންތަންގަނޑު އެއުރެންގެ މައްޗަށް ވައްޓަވައިފާހުށީމެވެ. ހަމަކަށަވަރުން، އެކަމުގައި އެކަލާނގެއަށް ތައުބާވެ، ރުޖޫއަވާ ކޮންމެ އަޅަކަށް ހެތްކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","ولقد آتينا داوود منا فضلا يا جبال أوبي معه والطير وألنا له الحديد","އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ދާވޫދުގެފާނަށް ތިމަންރަސްކަލާނގެ ހަޒުރަތުން ފަޟްލު ވަންތަކަން (އެބަހީ: ނަބީކަމާއި ފޮތް) ދެއްވީމެވެ. (އަދި ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވީމެވެ.) އޭ ފަރުބަދަތަކާއެވެ! އެކަލޭގެފާނާއެކު ތިޔަ ފަރުބަދަތައް ތަސްބީހަ ކިޔާށެވެ! އަދި ދޫނިސޫފާސޫތްޕާ އެކުގައެވެ. އަދި އެކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ ދަގަނޑު، މަޑުއެއްޗަކަށް ހެއްދެވީމެވެ.","",""],["","","","أن اعمل سابغات وقدر في السرد واعملوا صالحا إني بما تعملون بصير","(ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ވަހީކުރެއްވީމެވެ.) ތިމާމެންގެ ހަށިތައް ނިވައިކޮށް ރައްކާތެރިކުރާ ދަހަނާތައް ހައްދަވާށެވެ! އަދި ދަހަނާތައް ހެއްދެވުމުގައި، މިންތައް ބައްލަވައި، ރަނގަޅަށް ހަމަކުރައްވާށެވެ! އަދި ތިޔަބައިމީހުން ސާލިހު ޢަމަލުކުރާށެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެއީ، ތިޔަބައިމީހުންކުރާ ކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ولسليمان الريح غدوها شهر ورواحها شهر وأسلنا له عين القطر ومن الجن من يعمل بين يديه بإذن ربه ومن يزغ منهم عن أمرنا نذقه من عذاب السعير","އަދި ސުލައިމާނުގެފާނަށް ތިމަންރަސްކަލާނގެ ވައިރޯޅި ކިޔަމަންކުރެއްވީމެވެ. އެ ވައިރޯޅީގެ ހެނދުނުގެ (އެބަހީ: މެންދުރުކުރީގެ) ދަތުރަކީ މަސްދުވަހުގެ ރާސްތާއެވެ. އަދި އެ ވައިރޯޅީގެ ހަވީރުގެ (އެބަހީ: މެންދުރުފަހުގެ) ދަތުރަކީ މަސްދުވަހުގެ ރާސްތާއެވެ. އަދި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ރަތުލޯވިރުވައި ދެއްވީމެވެ. އަދި އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އަމުރު ފުޅާއެކު، އެކަލޭގެފާނުގެ ކުރިފުޅުމަތީގައި މަސައްކަތްކުރާ ބަޔަކު، ޖިންނީންގެ ތެރެއިން ލެއްވީމެވެ. އެ ޖިންނީންގެ ތެރެއިން، ތިމަންރަސްކަލާނގެ އަމުރުފުޅުން އެއްކިބާވެ، ނުކިޔަމަންތެރިވާ ބަޔަކަށް، ނަރަކައިގެ ހުޅުގަނޑުގެ އަޒާބުގެ ރަހަ ތިމަންރަސްކަލާނގެ ދައްކަވާހުށީމެވެ. (ނޯޓު: ވައިރޯޅީގެ މަސްދުވަހުގެ ދަތުރޭ ބުނެވުނީ ފައިމަގުގައި ހިނގާ ދަތުރުވެރިޔަކަށް މަސްދުވަހުން ދެވޭހާހިސާބަށް ވައިރޯޅީގެ ބޭނުންކުރައްވައިގެން ހެނދުނު ދަތުރެއް، ހަވީރު ދަތުރެއް ކުރެއްވޭނެގޮތް، ﷲ، ސުލައިމާނުގެފާނަށް މެދުވެރިކޮށްދެއްވުމަށެވެ.)","",""],["","","","يعملون له ما يشاء من محاريب وتماثيل وجفان كالجواب وقدور راسيات اعملوا آل داوود شكرا وقليل من عبادي الشكور","އުސްވެގެންވާ ބިނާތަކާއި، ސިފަސިފައިގެ ބުދުތަކާއި، ބޮޑެތި ބިލިގާތަކެއްފަދަ ތަށިތަކާއި، ހަރުލައި ހުންނަ ބިޔަ ތެލިތަކާއި، މިތަކެތީގެ ތެރެއިން އެކަލޭގެފާނު އެދިވަޑައިގަންނަވާ އެއްޗެއް އެއުރެން އެކަލޭގެފާނަށް ހަދައިދެތެވެ. އޭ ދާވޫދުގެފާނުގެ އާލުންނޭވެ! (އެކަލާނގެއަށް) ޝުކުރުވެރިވުމުގެގޮތުން ތިޔަބައިމީހުން (ހެޔޮ) ޢަމަލުކުރާށެވެ! އަދި ތިމަންރަސްކަލާނގެ އަޅުތަކުންގެ ތެރެއިން ގިނައިން ޝުކުރުވެރިވާ މީހުން ވަރަށްމަދެވެ.","",""],["","","","فلما قضينا عليه الموت ما دلهم على موته إلا دابة الأرض تأكل منسأته فلما خر تبينت الجن أن لو كانوا يعلمون الغيب ما لبثوا في العذاب المهين","ދެންފަހެ، އެކަލޭގެފާނު އަވަހާރަވުމަށް ތިމަންރަސްކަލާނގެ ނިޔާކުރެއްވިހިނދު، ކަތުރުފަނި ނޫންއެއްޗެއް އެއުރެންނަށް އެކަލޭގެފާނު އަވަހާރަވެއްޖެކަމަށް ނޭންގިއެވެ. އެ ކަތުރުފަނި އެކަލޭގެފާނުގެ އަސާކޮޅު ކަމުންގެންދިޔައެވެ. ދެންފަހެ، އެކަލޭގެފާނު ވެއްޓިވަޑައިގަތުމުން، ޖިންނީންނަށް އެނގިއްޖައޫއެވެ. ހަމަކަށަވަރުން، އެއުރެންނަށް ޣައިބު އެނގޭނަމަ، އިހާނަތްތެރިކަން ދެނިވި އަޒާބުގައި (އެބަހީ: ގަދަ މަސައްކަތުގައި) އެއުރެން ނުތިބީހެވެ.","",""],["","","","لقد كان لسبإ في مسكنهم آية جنتان عن يمين وشمال كلوا من رزق ربكم واشكروا له بلدة طيبة ورب غفور","ހަމަކަށަވަރުން، ސަބާގެ އަހުލުވެރިން އުޅުނުތާނގައި، އެއުރެންނަށް ކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެތްކެއްވިއެވެ. (އެއީ) ދެ ބަގީޗާއެކެވެ. (އެރަށުގެ) ކަނާތްފަރާތުންނާއި، ވާތްފަރާތުންނެވެ. (އަންގަވާފަދައެވެ.) ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ދެއްވި ރިޒްގުން ތިޔަބައިމީހުން ކައިއުޅޭށެވެ! އަދި ތިޔަބައިމީހުން އެކަލާނގެއަށް ޝުކުރުވެރިވާށެވެ! (ތިޔަބައިމީހުންގެ ރަށަކީ) ރަނގަޅު، މޮޅު ރަށެކެވެ. އަދި ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަސްކަލާނގެއެވެ.","",""],["","","","فأعرضوا فأرسلنا عليهم سيل العرم وبدلناهم بجنتيهم جنتين ذواتي أكل خمط وأثل وشيء من سدر قليل","ދެން އެއުރެން (އެކަލާނގެ ނިއުމަތަށް) ފުރަގަސްދިނޫއެވެ. ދެން ތިމަންރަސްކަލާނގެ އެއުރެންގެމައްޗަށް ފައިބައިގެން އަންނަ ބޮޑުވެގެންވާ ފެންގަނޑު (އެބަހީ: سيل العرِم) ފޮނުއްވީމެވެ. އަދި އެއުރެންގެ ދެ ބަގީޗާގެ ބަދަލުގައި، އެއުރެންނަށް ތިމަންރަސްކަލާނގެ އެހެން ދެ ބަގީޗާ ދެއްވީމެވެ. ކާންނުކެރޭފަދަ ހިތި މޭވާގެ ގަސްތަކަކާއި، މޭވާއެއްނެތް ކަށިގަސްތަކަކާއި، އެތަންމިތާނގައި ވަރަށްމަދު ކުންނާރު ގަސްތަކެއްހުރި ދެ ބަގީޗާއެވެ.","",""],["","","","ذلك جزيناهم بما كفروا وهل نجازي إلا الكفور","އެ ޖަޒާ އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ދެއްވީ، އެއުރެން ކާފިރު ވުމުގެ ސަބަބުންނެވެ. ކާފިރުވާ މީހުންނަށް މެނުވީ، ތިމަންރަސްކަލާނގެ އެފަދަ ޖަޒާ ދެއްވަމުހެއްޔެވެ؟","",""],["","","","وجعلنا بينهم وبين القرى التي باركنا فيها قرى ظاهرة وقدرنا فيها السير سيروا فيها ليالي وأياما آمنين","އަދި ތިމަންރަސްކަލާނގެ އެ ރަށްތަކުގައި ބަރަކާތް ލެއްވި ރަށްތަކާއި، އެއުރެންނާ ދެމެދުގައި (ލޮލަށް ފެންނަހާ ކައިރީގައި) ފާޅުވެގެންވާ ރަށްތަކެއް ލެއްވީމެވެ. އަދި އެ ރަށްތަކުގައި ހިނގާބިނގާއުޅުން ތިމަންރަސްކަލާނގެ މިންވަރު ކުރެއްވީމެވެ. (ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ވަހީކުރެއްވީމެވެ.) ރޭތަކަކާއި، ދުވަސްތަކެއް ވަންދެން އަމާންކަން ލިބިގެންވާ ޙާލު، ތިޔަބައިމީހުން އެ ރަށްތަކުގައި ހިނގާބިނގާ ދަތުރުފަތުރުކޮށް އުޅޭށެވެ!","",""],["","","","فقالوا ربنا باعد بين أسفارنا وظلموا أنفسهم فجعلناهم أحاديث ومزقناهم كل ممزق إن في ذلك لآيات لكل صبار شكور","ފަހެ، އެއުރެން (ދުއާ ކޮށް) ދެންނެވޫއެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޯއެވެ! އަޅަމެންގެ ދަތުރުތަކުގެ ދެމެދުތައް މިއަށްވުރެން ދުރުކުރައްވައިފާނދޭވެ! އަދި އެއުރެން، އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް އަނިޔާވެރިވޫއެވެ. ދެންފަހެ، އެއުރެންނީ (މީސްތަކުންގެ މެދުގައި) ދެކެވޭ ވާހަކަތަކެއް ކަމުގައި، ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ. އަދި އެތަންމިތަނަށް ތިމަންރަސްކަލާނގެ އެއުރެން ވަކިކުރައްވައި ވިއްސިވިހާލި ކުރެއްވީމެވެ. ހަމަކަށަވަރުން، އެކަމުގައި ބޮޑަށް ކެތްތެރިވެ، ގިނަގިނައިން ޝުކުރުވެރިވާ ކޮންމެ މީހަކަށް ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","ولقد صدق عليهم إبليس ظنه فاتبعوه إلا فريقا من المؤمنين","ހަމަކަށަވަރުން، އިބްލީސް، އޭނާގެ ހީ، އެއުރެންގެ މައްޗަށް ސީދާކޮށްފިއެވެ. ފަހެ، މުއުމިނު ންކުރެ ބަޔަކުމެނުވީ، އެ އެންމެން، އިބްލީސާ ތަބާ ވޫއެވެ.","",""],["","","","وما كان له عليهم من سلطان إلا لنعلم من يؤمن بالآخرة ممن هو منها في شك وربك على كل شيء حفيظ","އަދި އާޚިރަތަށް އީމާންވާ މީހުންނާއި، އާޚިރަތާމެދު ޝައްކުކަމެއްގައިވާ މީހުން ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގެން، އެކަން ހާމަކުރެއްވުމަށްޓަކައިމެނުވީ، އެއުރެންގެ މައްޗަށް އެއްވެސް ބާރެއް، އެ އިބްލީސަކަށް ލިބިގެނެއް ނުވެތެވެ. އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ކޮންމެ އެއްޗެއްގެމައްޗަށް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","قل ادعوا الذين زعمتم من دون الله لا يملكون مثقال ذرة في السماوات ولا في الأرض وما لهم فيهما من شرك وما له منهم من ظهير","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲ ފިޔަވައި ތިޔަބައިމީހުން އެކަލާނގެއަށް ޝަރީކު ކޮށްއުޅުނު ފަރާތްތަކަށް ތިޔަބައިމީހުން ގޮވައިބަލާށެވެ! އުޑުތަކާއި، ބިމުގައި ޒައްރެއްގެ މިންވަރުވެސް އެއުރެންނަކަށް މިލްކުވެގެނެއް ނުވެތެވެ. އަދި އެ ދެތާނގައި އެއުރެންނަކަށް ބައިވެރިވުމެއްވެސްނެތެވެ. އަދި އެކަލާނގެއަށް އެއްވެސް އެހީތެރިޔަކު އެއުރެންގެ ތެރެޔަކުން ނުވެތެވެ.","",""],["","","","ولا تنفع الشفاعة عنده إلا لمن أذن له حتى إذا فزع عن قلوبهم قالوا ماذا قال ربكم قالوا الحق وهو العلي الكبير","އަދި އެމީހަކަށް އެކަލާނގެ އިޒުނަ ދެއްވައިފި މީހަކަށްމެނުވީ، އެކަލާނގެ ހަޒުރަތުގައި ޝަފާއަތް ތެރިކަމުން މަންފާއެއް ނުކުރާނެތެވެ. އެއުރެންގެ ހިތްތަކުން ބިރުވެރިކަން ކެނޑިއްޖައުމަށް ދާނދެނެވެ. (އެހިނދު) އެއުރެން (އެކަކުއަނެކަކަށް) ބުނާނެތެވެ. ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ވަހީކުރެއްވީ ކީކޭހެއްޔެވެ؟ އެއުރެން (އެކަކު އަނެކަކަށް) ބުނާނެތެވެ. (އެކަލާނގެ ވަހީކުރެއްވީ) ހައްގު ބަސްފުޅެވެ. އެކަލާނގެއީ، އެންމެ މަތިވެރި، އެންމެ ޢަޡަމަތް ތެރި ރަސްކަލާނގެއެވެ.","",""],["","","","قل من يرزقكم من السماوات والأرض قل الله وإنا أو إياكم لعلى هدى أو في ضلال مبين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އުޑުތަކާއި، ބިމުން ތިޔަބައިމީހުންނަށް ރިޒްގު ދެއްވަނީ ކާކުހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! (ރިޒްގު ދެއްވަނީ) ﷲއެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންމެން ނުވަތަ ތިޔަބައިމީހުންވަނީ، ތެދުމަގުގައި، ނުވަތަ ބަޔާންވެގެންވާ މަގުފުރެދުމެއްގައިކަން ކަށަވަރެވެ.","",""],["","","","قل لا تسألون عما أجرمنا ولا نسأل عما تعملون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންމެން ކުޅަ ފާފަޔާމެދު ތިޔަބައިމީހުންނާ ސުވާލެއް ނުކުރައްވާނެތެވެ. އަދި ތިޔަބައިމީހުން ކުރަމުންގެންދާ (ނުބައި) ޢަމަލު ތަކާމެދުވެސް، ތިމަންމެންނަކާ ސުވާލެއް ނުކުރައްވާނެތެވެ.","",""],["","","","قل يجمع بيننا ربنا ثم يفتح بيننا بالحق وهو الفتاح العليم","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންމެންގެ ވެރިރަސްކަލާނގެ (ގިޔާމަތް ދުވަހުން) ތިމަންމެން އެންމެން އެއްތަނަކަށް އެއްކުރައްވާނެތެވެ. ދެން ތިމަންމެންގެ މެދުގައި އެކަލާނގެ ހައްގަށް ނިޔާކުރައްވައި، ހުކުމްކުރައްވާނެތެވެ. އަދި އެކަލާނގެއީ، މޮޅަށް ހުކުމްކުރައްވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","قل أروني الذين ألحقتم به شركاء كلا بل هو الله العزيز الحكيم","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ބައިވެރިން ކަމުގައި އެކަލާނގެއަށް ތިޔަބައިމީހުން ނިސްބަތްކުރި ފަރާތްތައް ތިމަންނާއަށް ތިޔަބައިމީހުން ދައްކައިބަލާށެވެ! ހަމަހިލާ އެހެންނަކުން ނޫނެވެ! އަދި ކިއެއްތަ! އެކަލާނގެއީ، ޢަޒީޒުވަންތަ ޙަކީމްވަންތަ ﷲއެވެ.","",""],["","","","وما أرسلناك إلا كافة للناس بشيرا ونذيرا ولكن أكثر الناس لا يعلمون","އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު ކަމުގައްޔާއި، ބިރުވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު ކަމުގައިމެނުވީ، ތިމަންރަސްކަލާނގެ، އެންމެހާ މީސްތަކުންގެ ގާތަކަށް ކަލޭގެފާނު ނުފޮނުއްވަމެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުން (އެކަމެއް) ނުދަނެތެވެ.","",""],["","","","ويقولون متى هذا الوعد إن كنتم صادقين","އެއުރެން ބުނެތެވެ. ތިޔަބައިމީހުންނީ، ތެދުބުނާ ބަޔަކު ކަމުގައިވާނަމަ، ތިޔަ (ބުނާ އަޒާބުގެ) ވައުދު އަންނާނީ ކޮންއިރަކުން ހެއްޔެވެ؟","",""],["","","","قل لكم ميعاد يوم لا تستأخرون عنه ساعة ولا تستقدمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެ ވައުދަށް ކަނޑައަޅުއްވާފައިވާ ދުވަހެއް ތިޔަބައިމީހުންނަށްވެއެވެ. އެދުވަހަށްވުރެ އެންމެހިނދުކޮޅަކަށްވެސް ތިޔަބައިމީހުންނަކަށް ލަހެއް ނުކުރައްވާހުށްޓެވެ. އަދި އިހެއްވެސް ނުމެކުރައްވާހުށްޓެވެ.","",""],["","","","وقال الذين كفروا لن نؤمن بهذا القرآن ولا بالذي بين يديه ولو ترى إذ الظالمون موقوفون عند ربهم يرجع بعضهم إلى بعض القول يقول الذين استضعفوا للذين استكبروا لولا أنتم لكنا مؤمنين","އަދި ކާފިރު ވިމީހުން ބުނޫއެވެ. ތިމަންމެން މި ގުރްއާނަކަށްވެސް، އަދި މީގެކުރީގެ ފޮތްތަކަކަށްވެސް އީމާނެއް ނުވާނަމެވެ. އަނިޔާވެރިން އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ހުއްޓިތިބޭހިނދު، ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނެނަމައެވެ. (އެހިނދު) އެއުރެން އެއްބަޔަކު އަނެއްބަޔަކަށް ބަސްބުނެ ރައްދުކޮށް ހަދާނެތެވެ. ނިކަމެތިވެގެންވާ މީހުން، ބޮޑާވެގަތް މީހުންނަށް ބުނާނެތެވެ. ތިޔަބައިމީހުން ނުވާނަމަ، ތިމަންމެން މުއުމިނު ންކަމުގައި ވީސްކަން ކަށަވަރެވެ.","",""],["","","","قال الذين استكبروا للذين استضعفوا أنحن صددناكم عن الهدى بعد إذ جاءكم بل كنتم مجرمين","ބޮޑާވެގަތްމީހުން، ނިކަމެތިވެގެންވާ މީހުންނަށް ބުނޫއެވެ. ތިޔަބައިމީހުންނާ ހަމަޔަށް ތެދުމަގު އައުމަށްފަހު، އެ ތެދުމަގުން ތިޔަބައިމީހުން އެއްކިބާކުރީ ތިމަންމެން ހެއްޔެވެ؟ އަދި ކިއެއްތަ! ތިޔަބައިމީހުންނީ، ކުށްކުރާބަޔަކު ކަމުގައިވީމުއެވެ.","",""],["","","","وقال الذين استضعفوا للذين استكبروا بل مكر الليل والنهار إذ تأمروننا أن نكفر بالله ونجعل له أندادا وأسروا الندامة لما رأوا العذاب وجعلنا الأغلال في أعناق الذين كفروا هل يجزون إلا ما كانوا يعملون","އަދި ނިކަމެތިވެގެންވާ މީހުން، ބޮޑާވެގަތް މީހުންނަށް ބުނޫއެވެ. އަދި ކިއެއްތަ! އެއީ (ތިޔަބައިމީހުންގެ) ރެޔާދުވާލުގެ މަކަރެވެ. އެއީ ﷲއަށް ތިމަންމެން ކާފިރުވެ، އަދި އެކަލާނގެއަށް ޝަރީކުންތަކެއް ލުމަށް ތިޔަބައިމީހުން ތިމަންމެންނަށް އަމުރުކުޅަހިނދެވެ. އަދި އެއުރެން އަޒާބު ދުށްހިނދު، އެކަމުގެ މައްޗަށް ހިތާމަކޮށް އެކަން ވަންހަނާކުޅައޫއެވެ. އަދި ކާފިރުވި މީހުންގެ ކަނދުރާތަކުގައި، ތިމަންރަސްކަލާނގެ ކަސްތޮޅުތައް ލެއްވީމެވެ. (ފަހެ) އެއުރެން ޢަމަލުކުރަމުންގެންދިޔަ ގޮތަށްމެނުވީ، އެއުރެންނަށް ޖަޒާ ލިބޭނެހެއްޔެވެ؟","",""],["","","","وما أرسلنا في قرية من نذير إلا قال مترفوها إنا بما أرسلتم به كافرون","އެރަށެއްގައިތިބި ތަނަވަސްކަމުގައި ހައްދުފަހަނަޅައިފައިވާ މީހުން ތިމަންމެން މިތިބީ، ތިޔަ ރަސޫލުން އެކަމަކާއިގެން ފޮނުއްވެވި ކަމަކަށް ހަމަކަށަވަރުން، ކާފިރު ވެގެންނޭ ނުބުނާ އެއްވެސް ރަށަކަށް، ބިރުވެރިކަމުގެ ޚަބަރު ދެއްވާ ރަސޫލަކު ތިމަންރަސްކަލާނގެ ނުފޮނުއްވަމެވެ.","",""],["","","","وقالوا نحن أكثر أموالا وأولادا وما نحن بمعذبين","އަދި އެއުރެން ބުނޫއެވެ. މުދަލުގެ ގޮތުންނާއި، ދަރިންގެގޮތުން، ތިމަންމެން މާގިނައެވެ. އަދި ތިމަންމެންނީ (އާޚިރަތުގައި) އަޒާބު ދެއްވާނެ ބަޔަކު ކަމުގައި ނުވަމުއެވެ.","",""],["","","","قل إن ربي يبسط الرزق لمن يشاء ويقدر ولكن أكثر الناس لا يعلمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ތިމަންގެ ވެރިރަސްކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ރިޒްގު ތަނަވަސްކޮށްދެއްވަތެވެ. އަދި (އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ރިޒްގު) ދަތިކުރައްވަތެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުން އެކަމެއް ނުދަނެތެވެ.","",""],["","","","وما أموالكم ولا أولادكم بالتي تقربكم عندنا زلفى إلا من آمن وعمل صالحا فأولئك لهم جزاء الضعف بما عملوا وهم في الغرفات آمنون","އަދި ތިޔަބައިމީހުންގެ މުދާވިޔަސް، އަދި ދަރިންވިޔަސް، އެއީ ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ތިޔަބައިމީހުން ކުއްތަންކުރާކަމެއް ކަމުގައި ނުވެތެވެ. އީމާންވެ ސާލިހު ޢަމަލު ކޮށްފިމީހާ މެނުވީއެވެ. ފަހެ، އެއުރެންކުޅަ ހެޔޮ ޢަމަލަށް ގިނަގުނަވެގެންވާ ސަވާބެއުރެންނަށް ހުށްޓެވެ. އަދި ސުވަރުގޭގެ މަތިވެރި ދަރަޖައިގައި، އެއުރެންވަނީ އަމާން ކަން ލިބިގެންވާ ބަޔަކުކަމުގައެވެ.","",""],["","","","والذين يسعون في آياتنا معاجزين أولئك في العذاب محضرون","އަދި ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާމެދު ދެކޮޅުހަދަން މަސައްކަތްކުރާ މީހުން (ދަންނާށެވެ!) އެއުރެން އަޒާބުގެތެރެޔަށް ޙާޒިރުުކުރައްވާނެތެވެ.","",""],["","","","قل إن ربي يبسط الرزق لمن يشاء من عباده ويقدر له وما أنفقتم من شيء فهو يخلفه وهو خير الرازقين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ތިމަންގެ ވެރިރަސްކަލާނގެ، އެކަލާނގެ އަޅުންގެ ތެރެއިން އިރާދަކުރައްވާ އަޅަކަށް ރިޒްގު ތަނަވަސްކޮށްދެއްވަތެވެ. އަދި އެކަލާނގެ (އިރާދަކުރައްވާ) އަޅަކަށް (ރިޒްގު) ދަތިކުރައްވަތެވެ. އަދި ތިޔަބައިމީހުން (އެކަލާނގެ މަގުގައި) ހޭދަކުރި ކޮންމެ އެއްޗަކަށް، އެކަލާނގެ އޭގެ ބަދަލު ދެއްވަތެވެ. އަދި އެކަލާނގެއީ، ރިޒްގު ދެއްވާ، އެންމެހެޔޮ ރަސްކަލާނގެއެވެ.","",""],["","","","ويوم يحشرهم جميعا ثم يقول للملائكة أهؤلاء إياكم كانوا يعبدون","އެކަލާނގެ އެއުރެން އެންމެން މަހުޝަރަށް ފޮނުއްވާ ދުވަސް ހަނދުމަކުރާށެވެ! ދެން އެކަލާނގެ މަލާއިކަތުންނަށް ވަހީކުރައްވާނެތެވެ. ތިޔަބައިމީހުންނަށް އަޅުކަންކުރާ ކަމުގައިވީ މިތިބަމީހުން ހެއްޔެވެ؟","",""],["","","","قالوا سبحانك أنت ولينا من دونهم بل كانوا يعبدون الجن أكثرهم بهم مؤمنون","އެ މަލާއިކަތުން ދަންނަވާނެތެވެ. އިބަރަސްކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! އިބަރަސްކަލާނގެއީ، އަޅަމެންގެ އެހީތެރިވަންތަ ރަސްކަލާނގެއެވެ. އެއުރެންނެއްނޫނެވެ. އަދި ކިއެއްތަ! އެއުރެން އަޅުކަންކުރާ ކަމުގައިވީ ޖިންނީންނަށެވެ. އެއުރެންކުރެ ގިނަމީހުންވަނީ، އެ ޖިންނީންނަށް އީމާން ވެގެންނެވެ.","",""],["","","","فاليوم لا يملك بعضكم لبعض نفعا ولا ضرا ونقول للذين ظلموا ذوقوا عذاب النار التي كنتم بها تكذبون","ފަހެ، މިއަދު ތިޔަބައިމީހުންކުރެ އެއްބަޔަކަށް އަނެއްބަޔަކު މަންފާއެއް ކުރުމެއްވިޔަސް، ނުވަތަ ގެއްލުމެއް ދިނުންވިޔަސް، މިލްކުވެގެންނެއް ނުވެތެވެ. އަދި އަނިޔާވެރިވީ މީހުންނަށް ތިމަންރަސްކަލާނގެ ވަހީކުރައްވާހުށީމެވެ. ތިޔަބައިމީހުން ދޮގުކޮށްއުޅުނު ނަރަކައިގެ އަޒާބުގެ ރަހަ، ތިޔަބައިމީހުން ލިބިގަންނާށެވެ!","",""],["","","","وإذا تتلى عليهم آياتنا بينات قالوا ما هذا إلا رجل يريد أن يصدكم عما كان يعبد آباؤكم وقالوا ما هذا إلا إفك مفترى وقال الذين كفروا للحق لما جاءهم إن هذا إلا سحر مبين","އަދި އެއުރެންނަށް ތިމަންރަސްކަލާނގެ އާޔަތްތައް ބަޔާންވެގެންވާ ގޮތުގައި ކިޔައިދެއްވާހިނދު، އެއުރެން ބުނެތެވެ. ތިޔަބައިމީހުންގެ ކާބަފައިން އަޅުކަންކޮށްއުޅުނު ތަކެތިން، ތިޔަބައިމީހުން އެއްކިބާކުރުމަށް ގަސްދު ކޮށްގެންއުޅޭ މީހަކުކަމުގައި މެނުވީ، މީނާ (އެބަހީ: ރަސޫލާ) ނުވެތެވެ. އަދި އެއުރެން ބުނެތެވެ. އަމިއްލައަށް އުފައްދާފައިވާ ދޮގެއް ކަމުގައި މެނުވީ މި (ގުރްއާން) ނުވެތެވެ. އަދި އެއުރެންނަށް، ހައްގު ގުރުއާން އައިހިނދު، އެ ގުރްއާނާމެދު ކާފިރު ވިމީހުން ބުނޫއެވެ. ފާޅުވެގެންވާ ޖާދޫއެއްކަމުގައި މެނުވީ މި ނުވެތެވެ.","",""],["","","","وما آتيناهم من كتب يدرسونها وما أرسلنا إليهم قبلك من نذير","އަދި އެއުރެން ކިޔަވައިއުޅޭނެ ފޮތްތަކެއް، ތިމަންރަސްކަލާނގެ އެއުރެންނަކަށް ނުދެއްވަމެވެ. އަދި އެއުރެންގެގާތަށް ބިރުވެރިކަމުގެ ޚަބަރު ދެއްވާ އެއްވެސް ރަސޫލަކު ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނުގެ ކުރިޔަކުން ނުފޮނުއްވަމެވެ.","",""],["","","","وكذب الذين من قبلهم وما بلغوا معشار ما آتيناهم فكذبوا رسلي فكيف كان نكير","އަދި އެއުރެންގެ ކުރީގެ މީހުންވެސް ދޮގުކުރޫއެވެ. އަދި އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ދެއްވި އާރާއި ބާރުގެ ދިހަބައިކުޅައެއްބަޔާ ހަމަޔަށްވެސް އެއުރެންނެއް (އެބަހީ: މައްކާގެ މުޝްރިކުން) ނުފޯރަތެވެ. ފަހެ، އެއުރެން ތިމަންރަސްކަލާނގެ ފޮނުއްވި ރަސޫލުން ދޮގުކުޅައޫއެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ އިންކާރުކުރެއްވުންވީ، ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","قل إنما أعظكم بواحدة أن تقوموا لله مثنى وفرادى ثم تتفكروا ما بصاحبكم من جنة إن هو إلا نذير لكم بين يدي عذاب شديد","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަން، ތިޔަބައިމީހުންނަށް ނަސޭހަތް ތެރިވާކަން ކަށަވަރީ، އެންމެކަމަކަށެވެ. (އެއީ) ތިޔަބައިމީހުން ދޭދޭމީހުންނާއި، ވަކިވަކިން ﷲއަށްޓަކައި (ހައްގު މަގު ހޯދުމުގައި) ގާއިމު ވެތިބުމަށެވެ. ދެން ތިޔަބައިމީހުން ވިސްނައި ފިކުރުކުރުމަށެވެ. ތިޔަބައިމީހުންގެ އެކުވެރިޔާ (އެބަހީ: މުޙައްމަދުގެފާނު) ގެ ކިބައިގައި އެއްވެސް މޮޔަކަމެއްނެތެވެ. ގަދަވެގެންވާ އަޒާބެއްގެކުރިން އެއާމެދު ތިޔަބައިމީހުންނަށް ބިރުވެރިކަމުގެ ޚަބަރު ދެއްވާ ރަސޫލަކުކަމުގައި މެނުވީ އެކަލޭގެފާނު ނުވެތެވެ.","",""],["","","","قل ما سألتكم من أجر فهو لكم إن أجري إلا على الله وهو على كل شيء شهيد","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންގެ ކިބައިން އެއްވެސް އުޖޫރައަކަށް ތިމަންއެދިފައިވާނަމަ، ފަހެ، އެއީ ތިޔަބައިމީހުންނަށެވެ. ތިމަންނައަށް ދަރުމަދެއްވުން ﷲއަށް މެނުވީ ނުވެތެވެ. އަދި އެކަލާނގެއީ، ކޮންމެކަމެއްގެ މައްޗަށް މޮޅަށް ހެކިވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","قل إن ربي يقذف بالحق علام الغيوب","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ތިމަންގެ ވެރިރަސްކަލާނގެ ހައްގު ގޮތް ފޮނުއްވަތެވެ. (އެކަލާނގެއީ) ޣައިބުތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","قل جاء الحق وما يبدئ الباطل وما يعيد","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހައްގު ތެދުގޮތް އަތުވެއްޖެއެވެ. އަދި ބާތިލަކަށް (އެއްވެސް އެއްޗެއް) ނުއުފެއްދޭނެތެވެ. އަދި އިޢާދެއްވެސް ނުމެކުރެވޭނެމެއެވެ.","",""],["","","","قل إن ضللت فإنما أضل على نفسي وإن اهتديت فبما يوحي إلي ربي إنه سميع قريب","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަން މަގުފުރެދިއްޖެނަމަ، ފަހެ، ތިމަން މަގުފުރެދޭކަން ކަށަވަރީ، ތިމަންގެ އަމިއްލަ ނަފްސުގެ މައްޗަށެވެ. (އެބަހީ: އެކަމުގެ ގެއްލުންހުރީ ތިމަންގެ އަމިއްލަ ނަފްސަށެވެ.) އަދި ތިމަންނާއަށް ތެދުމަގު ލިބިއްޖެނަމަ، ފަހެ، އެއީ ތިމަންގެ ވެރިރަސްކަލާނގެ ތިމަންނާއަށް އިއްވަވާ ވަހީގެ ސަބަބުންނެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، ކުއްތަންވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ولو ترى إذ فزعوا فلا فوت وأخذوا من مكان قريب","އެއުރެން (ގިޔާމަތް ދުވަހު) ބިރުން ސިހިގެންދާހިނދު ކަލޭގެފާނު ދެކެވައިގަންނަވާނެނަމައެވެ. ފަހެ، އެހިނދު ސަލާމަތްވެގެން ދިއުމެއްނެތެވެ. އަދި ގާތުގައިވާ ތަނަކުން އެއުރެން ހިއްޕަވައި ގެންދަވާނެތެވެ.","",""],["","","","وقالوا آمنا به وأنى لهم التناوش من مكان بعيد","އަދި އެއުރެން ބުނާނެތެވެ. ތިމަންމެން (މިހާރު) އެ ގުރްއާނަށް އީމާން ވެއްޖައީމެވެ. ދުރުގައިވާ ތަނަކުން އެ އީމާން ކަން އެއުރެންނަށް ލިބޭނީ ކިހިނަކުން ހެއްޔެވެ؟","",""],["","","","وقد كفروا به من قبل ويقذفون بالغيب من مكان بعيد","މީގެކުރިން އެއުރެންވަނީ އެ ގުރްއާނަށް ކާފިރު ވެފައިކަން ކަށަވަރެވެ. އަދި ނުފެންނަ ކަންތަކާމެދު ދުރުތަނަކުން އެއުރެން ހީއެއްގެ މައްޗަށް ވާހަކަދައްކައި އުޅުނޫއެވެ.","",""],["","","","وحيل بينهم وبين ما يشتهون كما فعل بأشياعهم من قبل إنهم كانوا في شك مريب","އަދި އެއުރެން އެދޭކަންތަކާއި، އެއުރެންނާދެމެދު ހުރަސްއެޅުއްވިއެވެ. އެއުރެންނާ އެއްފަދަވެގެންވާ މީހުންނާމެދު، ކުރިން ކަންތައްކުރެއްވި ފަދައިންނެވެ. ހަމަކަށަވަރުން، އެއުރެންވީ ވަސްވާސްތެރިކަމުން ފުރިގެންވާ ޝައްކެއްގައެވެ.","",""],["","","","بسم الله الرحمن الرحيم الحمد لله فاطر السماوات والأرض جاعل الملائكة رسلا أولي أجنحة مثنى وثلاث ورباع يزيد في الخلق ما يشاء إن الله على كل شيء قدير","ހަމްދު ހުރީ ﷲއަށެވެ. އެކަލާނގެއީ، އިސްވެދިޔަ މިސާލަކާ ނުލައި އުޑުތަކާއި، ބިން އުފެއްދެވި ރަސްކަލާނގެއެވެ. ދޭކުން، ތިނަކުން، ހަތަރަކުން ފިޔަފުޅުތަކެއް ލިބިވަޑައިގެންފައިވާ މަލާއިކަތުން އެއީ (އެކިއެކި ކަންކަމާއިގެން) ފޮނުއްވާ ބަޔަކުކަމުގައި ލެއްވި ރަސްކަލާނގެއެވެ. ހެއްދެވުމުގައި އެކަލާނގެ އިރާދަކުރައްވާ ގޮތަކަށް އިތުރު ކުރައްވަތެވެ. ހަމަކަށަވަރުން ﷲއީ، ކޮންމެ ކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ما يفتح الله للناس من رحمة فلا ممسك لها وما يمسك فلا مرسل له من بعده وهو العزيز الحكيم","މީސްތަކުންނަށްޓަކައި ﷲއެއްވެސް ރަހުމަތެއް ހުޅުއްވަވާނަމަ، ފަހެ، އެ ރަހުމަތް ހިފަހައްޓާނެ މީހަކު ނުވެތެވެ. އަދި އެކަލާނގެ ކަމެއް ހިފަހައްޓަވާނަމަ، އެކަން އެކަލާނގެއަށްފަހު ވީއްލާނެ މީހަކު ނުވެތެވެ. އެކަލާނގެއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","يا أيها الناس اذكروا نعمت الله عليكم هل من خالق غير الله يرزقكم من السماء والأرض لا إله إلا هو فأنى تؤفكون","އޭ މީސްތަކުންނޭވެ! ﷲ ތިޔަބައިމީހުންނަށް ދެއްވި ނިއުމަތް ހަނދުމަކުރާށެވެ! ﷲ މެނުވީ ތަކެތި ހައްދަވާ، އުޑާއި ބިމުން ތިޔަބައިމީހުންނަށް ރިޒްގު ދެއްވާ ކަލަކު ވޭހެއްޔެވެ؟ އެކަލާނގެ މެނުވީ އިލާހަކު ނުވެއެވެ. ފަހެ، ތިޔަބައިމީހުން (އީމާންކަމުން) އެއްކިބާވެގަންނަނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","وإن يكذبوك فقد كذبت رسل من قبلك وإلى الله ترجع الأمور","އަދި އެއުރެން ކަލޭގެފާނު ދޮގުކުރާނަމަ، ފަހެ، ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ކުރިންވެސް ރަސޫލުން ދޮގުކުރެވުނެވެ. އަދި އެންމެހާ ކަންތައް ރުޖޫއަކުރައްވާހުށީ ﷲގެ ހަޒުރަތަށެވެ.","",""],["","","","يا أيها الناس إن وعد الله حق فلا تغرنكم الحياة الدنيا ولا يغرنكم بالله الغرور","އޭ މީސްތަކުންނޭވެ! ހަމަކަށަވަރުން، ﷲގެ ވައުދު ފުޅަކީ ހައްގު ތެދެވެ. ފަހެ، ދުނިޔޭގެ ދިރިއުޅުން ތިޔަބައިމީހުން ހެއްލުންތެރިކުރިޔަ ނުދޭހުށިކަމެވެ! އަދި ﷲއާމެދު ޝައިތާނާ ތިޔަބައިމީހުން ހެއްލުންތެރިކުރިޔަ ނުދޭހުށިކަމެވެ!","",""],["","","","إن الشيطان لكم عدو فاتخذوه عدوا إنما يدعو حزبه ليكونوا من أصحاب السعير","ހަމަކަށަވަރުން، ޝައިތާނާއަކީ، ތިޔަބައިމީހުންނަށްވާ އަދާވަތް ތެރިޔެކެވެ. ފަހެ، އެ ޝައިތާނާއީ، އަދާވަތް ތެރިޔަކު ކަމުގައި ތިޔަބައިމީހުން ދެކޭށެވެ! އޭނާގެ ޖަމާއަތަށް އޭނާ ގޮވާކަން ކަށަވަރީ، ނަރަކައިގެ އަހުލުވެރިންގެތެރެއިން ވުމަށެވެ.","",""],["","","","الذين كفروا لهم عذاب شديد والذين آمنوا وعملوا الصالحات لهم مغفرة وأجر كبير","ކާފިރުވި މީހުންނަށް ގަދަވެގެންވާ އަޒާބު ހުށްޓެވެ. އަދި އީމާންވެ ސާލިހު ޢަމަލުކުޅަ މީހުންނަށް ފާފަފުއްސެވުމާއި، ބޮޑުވެގެންވާ ދަރުމަހުށްޓެވެ.","",""],["","","","أفمن زين له سوء عمله فرآه حسنا فإن الله يضل من يشاء ويهدي من يشاء فلا تذهب نفسك عليهم حسرات إن الله عليم بما يصنعون","ފަހެ، އެމީހެއްގެ ނުބައި ޢަމަލު، އެމީހަކަށް ޒީނަތްތެރިކުރެވި އަދި އެއީ ރަނގަޅު ޢަމަލުކަމުގައި ދެކެފި މީހާ (ތެދުމަގު ލިބުނުމީހާއާ އެއްފަދަހެއްޔެވެ؟) ފަހެ، ހަމަށަވަރުން، ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ މީހަކު މަގުފުރައްދަވަތެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ތެދުމަގު ދައްކަވަތެވެ. ފަހެ، އެއުރެންގެ މައްޗަށް ހިތާމަކުރެއްވުމުގައި، ކަލޭގެފާނުގެ ނަފްސު ހަލާކުވިޔަނުދެއްވާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، އެއުރެން ކުރާކަންތައް މޮޅަށްދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","والله الذي أرسل الرياح فتثير سحابا فسقناه إلى بلد ميت فأحيينا به الأرض بعد موتها كذلك النشور","އަދި ﷲއީ، ވައިރޯޅި ފޮނުއްވި ރަސްކަލާނގެއެވެ. ފަހެ، އެ ވައިރޯޅި ވިލާތައް އުފުލައެވެ. އަދި މަރުވެފައިވާ ރަށަކަށް، ތިމަންރަސްކަލާނގެ އެ ވިލާތައް ގެންދެވީމެވެ. ފަހެ، ބިންގަނޑު މަރުވެފައި އޮތުމަށްފަހު، އެ ވިލާތަކުގެ ފެނުން ތިމަންރަސްކަލާނގެ އެ ބިން ދިރުއްވީމެވެ. (ގިޔާމަތް ދުވަހުން) އަލުން ދިރުއްވައި ފޮނުއްވުންވަނީވެސް އެފަދައިންނެވެ.","",""],["","","","من كان يريد العزة فلله العزة جميعا إليه يصعد الكلم الطيب والعمل الصالح يرفعه والذين يمكرون السيئات لهم عذاب شديد ومكر أولئك هو يبور","ޢިއްޒަތް ތެރިކަން އެދޭމީހާ (ދަންނާށެވެ!) ފަހެ، އެންމެހާ ޢިއްޒަތް، މިލްކުވެގެންވަނީ ﷲއަށެވެ. ރަނގަޅު ބަސްތައް އުފުލިގެންދަނީ، އެކަލާނގެ ހަޒުރަތަށެވެ. އަދި ސާލިހު ޢަމަލު އެކަލާނގެ ހަޒުރަތަށް އުފުލައްވަތެވެ. އަދި ނުބައި ކަންތައް ރާވައިހަދާ މީހުންނަށް، ގަދަވެގެންވާ އަޒާބު ހުށްޓެވެ. އަދި، ގެއްލި ހަލާކުވެދާނީ ހަމައެއުރެންގެ ރޭވުންތަކެވެ.","",""],["","","","والله خلقكم من تراب ثم من نطفة ثم جعلكم أزواجا وما تحمل من أنثى ولا تضع إلا بعلمه وما يعمر من معمر ولا ينقص من عمره إلا في كتاب إن ذلك على الله يسير","ވެލިން، ދެން މަނިތިއްކަކުން، ތިޔަބައިމީހުން ހެއްދެވީ ﷲއެވެ. ދެން ދެ ޖިންސުގެ މީހުން ކަމުގައި އެކަލާނގެ ތިޔަބައިމީހުން ލެއްވިއެވެ. އަދި އެކަލާނގެ ދެނެވޮޑިގަތުމާއެކުގައި މެނުވީ، އަންހެނަކު މާބަނޑެއް ނުވެތެވެ. އަދި ނުވެސް ވިހާމެއެވެ. އަދި ފޮތެއްގައި ކަނޑައަޅުއްވާފައިވާ ގޮތުން މެނުވީ، އުމުރު ދިގު މީހެއްގެ އުމުރު ދިގުވެގެން ނުދެތެވެ. އަދި އޭނާގެ އުމުރުކުރުވެގެންވެސް ނުމެދޭމެއެވެ. ހަމަކަށަވަރުން، އެކަންތަކަކީ، ﷲއަށް ދާދިފަސޭހަ ކަމެކެވެ.","",""],["","","","وما يستوي البحران هذا عذب فرات سائغ شرابه وهذا ملح أجاج ومن كل تأكلون لحما طريا وتستخرجون حلية تلبسونها وترى الفلك فيه مواخر لتبتغوا من فضله ولعلكم تشكرون","ދެކަނޑު ހަމަހަމަވެގެން ނުވެތެވެ. (އެބަހީ: ކަނޑުގެ ލޮނުގަނޑާއި ކޯރުގެ މީރު ފެން، ހަމަހަމަވެގެނެއް ނުވެތެވެ.) މިއީ މީރުކަން ބޮޑު، ބުއިމަށް ފަސޭހަ މީރު ފެނެވެ. އަދި މިއީ ލޮނުކަން ގަދަ ލޮނު ހިތި ފެނެވެ. އަދި އެއިން ކޮންމެ ތަނަކުން ތިޔަބައިމީހުން ތާޒާ މަސްކަމުއެވެ. އަދި ތިޔަބައިމީހުން އަޅައި އުޅޭ ގަހަނާ އެ ކަނޑުން ނެރެމުއެވެ. އަދި އެ ކަނޑުގައި ގޮސްއައިސްވާ އުޅަނދުތައް ތިބާ ދެކޭނޫއެވެ. (އެއީ) ތިޔަބައިމީހުން އެކަލާނގެ ފަޟްލު ވަންތަކަމުން އެދިގަތުމަށްޓަކައެވެ. އަދި ތިޔަބައިމީހުން ޝުކުރުކުރުމަށްޓަކައެވެ.","",""],["","","","يولج الليل في النهار ويولج النهار في الليل وسخر الشمس والقمر كل يجري لأجل مسمى ذلكم الله ربكم له الملك والذين تدعون من دونه ما يملكون من قطمير","އެކަލާނގެ ދުވާލުގެ ތެރެޔަށް ރޭގަނޑު ވައްދަވައި، އަދި ރޭގަނޑުގެ ތެރެޔަށް ދުވާލު ވައްދަވައި، އަދި އިރާއި ހަނދު ޚިދުމަތް ތެރިކުރެއްވިއެވެ. (އެއިން) ކޮންމެ އެއްޗެއް ކަނޑައެޅިގެންވާ މުއްދަތަކަށް ހިނގަހިނގާ ހުރެތެވެ. އެއީ ﷲއެވެ. (އެކަލާނގެއީ) ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއެވެ. ވެރިކަންވަނީ އެކަލާނގެއަށެވެ. އަދި އެކަލާނގެ ފިޔަވައި ތިޔަބައިމީހުން ގޮވައި އަޅުކަންކުރާ ފަރާތްތަކަށް ކަދުރު އޮށެއްގެ ބޭރުގެ ދުލިފަށުގެ މިންވަރުވެސް މިލްކުވެގެން ނުވެތެވެ.","",""],["","","","إن تدعوهم لا يسمعوا دعاءكم ولو سمعوا ما استجابوا لكم ويوم القيامة يكفرون بشرككم ولا ينبئك مثل خبير","ތިޔަބައިމީހުން އެފަރާތްތަކަށް ގޮވިޔަސް، އެފަރާތްތަކަށް ތިޔަބައިމީހުން ގޮވާ ގޮވުމެއް ނީވޭނެތެވެ. އަދި އެގޮވުން އެފަރާތްތަކަށް އިވުނުކަމަށްވިޔަސް، ތިޔަބައިމީހުންނަކަށް އެފަރާތްތަކެއް އިޖާބައެއް ނުދޭނެތެވެ. އަދި ތިޔަބައިމީހުން ޝަރީކުކުޅަކަމާމެދު ގިޔާމަތް ދުވަހުން އެފަރާތްތައް އިންކާރުކުރާނެތެވެ. ޚަބަރުތައް މޮޅަށް ދެނެވޮޑިގެންވާކަލާނގެ ފަދައިން ކަލޭގެފާނަށް ޚަބަރު ދޭނެ ހަމަ އެކަކުވެސް ނެތެވެ.","",""],["","","","يا أيها الناس أنتم الفقراء إلى الله والله هو الغني الحميد","އޭ މީސްތަކުންނޭވެ! ﷲއަށް ބޭނުންތެރިވެގެންވާ ބަޔަކީ ތިޔަބައިމީހުންނެވެ. އަދި ﷲއީ، ފުދިވޮޑިގެންވާ، ގިނަގިނައިން ހަމްދު ލިބިވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","إن يشأ يذهبكم ويأت بخلق جديد","އެކަލާނގެ އިރާދަކުރައްވާނަމަ، ތިޔަބައިމީހުން ނެތިކޮށްލައްވައި އާ މަޚްލޫގުންތަކެއް ގެންނަވައިފާހުށްޓެވެ.","",""],["","","","وما ذلك على الله بعزيز","އަދި އެކަންތައް ﷲއަށް އުނދަގޫ ކަމަކަށް ނުވެތެވެ.","",""],["","","","ولا تزر وازرة وزر أخرى وإن تدع مثقلة إلى حملها لا يحمل منه شيء ولو كان ذا قربى إنما تنذر الذين يخشون ربهم بالغيب وأقاموا الصلاة ومن تزكى فإنما يتزكى لنفسه وإلى الله المصير","އަދި ފާފަވެރި އެއްވެސް ނަފްސެއް، އެހެން ނަފްސެއްގެ ފާފައެއް ނުއުފުލާނެތެވެ. އަދި ފާފައިން ބަރުވެފައިވާ ނަފްސެއް، އެ އުފުލުމަށް (އެހެން ފަރާތަކަށް) ގޮވިޔަސް، އެއީ ގާތްތިމާގެކަމުގެ އަހުލުވެރިޔެއް ކަމުގައިވިޔަސް، އެއިން ހަމަ އެކައްޗެއްވެސް ނުއުފުލޭނެތެވެ. ކަލޭގެފާނު އިންޒާރުކުރައްވާކަން ކަށަވަރީ، ނުފެންނަތާނގައި އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ބިރުވެތިވެ، ނަމާދު ގާއިމު ކޮށްއުޅޭ މީހުންނަށެވެ. އަދި (ކާފިރުކަމުން) ތާހިރު ވެގަންނަމީހާ، ފަހެ، އެމީހާ ތާހިރު ވެގަންނަކަން ކަށަވަރީ، އޭނާގެ އަމިއްލަ ނަފްސަށްޓަކައެވެ. އަދި އެނބުރި ދިޔުންވަނީ ﷲގެ ހަޒުރަތަށެވެ.","",""],["","","","وما يستوي الأعمى والبصير","އަދި ކަނުމީހާއާއި، ލޮލަށް ފެންނަ މީހާއާ ހަމަހަމަވެގެން ނުވެތެވެ.","",""],["","","","ولا الظلمات ولا النور","އަދި އަނދިރިކަމާއި، އަލިކަމާވެސް ހަމަހަމަވެގެން ނުވެތެވެ.","",""],["","","","ولا الظل ولا الحرور","އަދި ހިޔަލާއި، ގަދަ އަތްވާވެސް ހަމަހަމަވެގެން ނުވެތެވެ.","",""],["","","","وما يستوي الأحياء ولا الأموات إن الله يسمع من يشاء وما أنت بمسمع من في القبور","އަދި ދިރިތިބި ތަކެއްޗާއި، މަރުވެފައިވާ ތަކެއްޗާ ހަމަހަމަވެގެން ނުވެތެވެ. ހަމަކަށަވަރުން، ﷲ އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް، އިއްވަވައިދެއްވަތެވެ. އަދި ކަށްވަޅުތަކުގައިވާ މީހުންނަށް އިއްވަވާ ބޭކަލަކު ކަމުގައި ކަލޭގެފާނު ނުވެތެވެ.","",""],["","","","إن أنت إلا نذير","އިންޒާރުކުރައްވާ ބޭކަލަކު ކަމުގައި މެނުވީ ކަލޭގެފާނު ނުވެތެވެ.","",""],["","","","إنا أرسلناك بالحق بشيرا ونذيرا وإن من أمة إلا خلا فيها نذير","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ހައްގު ދީނާއިގެން ކަލޭގެފާނު ފޮނުއްވީ، އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު ކަމުގައްޔާއި، ބިރުވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު ކަމުގައެވެ. އަދި އެ އުއްމަތަކަށް އިންޒާރުކުރައްވާ ބޭކަލަކު، އިސްވެގޮސްފައި ނުވާ އެއްވެސް އުއްމަތެއް ނުވެތެވެ.","",""],["","","","وإن يكذبوك فقد كذب الذين من قبلهم جاءتهم رسلهم بالبينات وبالزبر وبالكتاب المنير","އަދި އެއުރެން ކަލޭގެފާނު ދޮގުކުރާނަމަ، ފަހެ، އެއުރެންގެ ކުރީގެ މީހުންވެސް ހަމަކަށަވަރުން (ރަސޫލުން) ދޮގުކުޅައޫއެވެ. އެއުރެންގެ ގާތަށް އެއުރެންގެ ރަސޫލުން ވަޑައިގަތީ، ފާޅުވެގެންވާ ހެކިތަކާއި، ލިޔުއްވާފައިވާ ފޮތްތަކާއި، އަލިކުރަނިވި ފޮތާއިގެންނެވެ.","",""],["","","","ثم أخذت الذين كفروا فكيف كان نكير","ދެން ތިމަންރަސްކަލާނގެ، ކާފިރު ވިމީހުން ހިއްޕަވައި ގެންދެވީމެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ އުގޫބާތް ދެއްވުންވީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","ألم تر أن الله أنزل من السماء ماء فأخرجنا به ثمرات مختلفا ألوانها ومن الجبال جدد بيض وحمر مختلف ألوانها وغرابيب سود","ހަމަކަށަވަރުން، ﷲ އުޑުން ފެން ވެއްސެވިކަން ތިބާ ނުދަންނަމުހެއްޔެވެ؟ ފަހެ، ކުލަތައް ތަފާތުވެގެންވާ މޭވާތައް، އެ ފެނުގެ ސަބަބުން ތިމަންރަސްކަލާނގެ ނެރުއްވީމެވެ. އަދި ފަރުބަދަތަކުގެ ތެރޭގައި ހުދުކުލައާއި، ރަތްކުލައާއި، ކަޅުކަންގަދަ ކަޅުކުލައާއި، އަދި ކުލަތައް ތަފާތުވެގެންވާ މަގުތައް ހުރި ފަރުބަދަތައްވެއެވެ.","",""],["","","","ومن الناس والدواب والأنعام مختلف ألوانه كذلك إنما يخشى الله من عباده العلماء إن الله عزيز غفور","އަދި މީސްތަކުންގެ ތެރެއިންނާއި، ދިރޭ ތަކެތީގެ ތެރެއިންނާއި، ނަޢަމް ސޫފީގެ ތެރެއިންވެސް ހަމައެފަދައިން ކުލަތައް ތަފާތުވެގެންވާ ތަކެތިވެއެވެ. ﷲއަށް ބިރުވެތިވާކަން ކަށަވަރީ، އެކަލާނގެ އަޅުންގެތެރެއިން އިލްމުވެރިންނެވެ. ހަމަކަށަވަރުން، ﷲއީ، ޢަޒީޒުވަންތަ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަސްކަލާނގެއެވެ.","",""],["","","","إن الذين يتلون كتاب الله وأقاموا الصلاة وأنفقوا مما رزقناهم سرا وعلانية يرجون تجارة لن تبور","ހަމަށަވަރުން، ﷲގެފޮތް ކިޔަވައި، އަދި ނަމާދު ގާއިމު ކޮށް، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްވި ތަކެތިން ސިއްރާއި ފާޅުގައި ހޭދަކޮށްއުޅޭ މީހުންނީ، ގެއްލުން ނުވާނެ ވިޔަފާރިޔަކަށް އެދޭ ބަޔެކެވެ.","",""],["","","","ليوفيهم أجورهم ويزيدهم من فضله إنه غفور شكور","(އެއީ) އެކަލާނގެ އެއުރެންނަށް އެއުރެންގެ ދަރުމަ ހަމަޔަށް ދެއްވައި އަދި އެކަލާނގެ ފަޟްލު ވަންތަކަމުން އެއުރެންނަށް އިތުރުކޮށްދެއްވުމަށްޓަކައެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ގިނަގިނައިން ޝުކުރު ގަބޫލުކުރައްވާ ރަސްކަލާނގެއެވެ.","",""],["","","","والذي أوحينا إليك من الكتاب هو الحق مصدقا لما بين يديه إن الله بعباده لخبير بصير","ފޮތުގެ ތެރެއިން ކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ ވަހީކުރެއްވި ތަކެއްޗަކީ، އޭގެކުރީގައިވާ ފޮތްތައް ތެދުކުރާ ހައްގު ތެދުބަސްފުޅެވެ. ހަމަކަށަވަރުން، ﷲއީ، އެކަލާނގެ އަޅުތަކުންގެ ޚަބަރުތައް މޮޅަށް ދެނެވޮޑިގެންވާ، މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","ثم أورثنا الكتاب الذين اصطفينا من عبادنا فمنهم ظالم لنفسه ومنهم مقتصد ومنهم سابق بالخيرات بإذن الله ذلك هو الفضل الكبير","ދެން ތިމަންރަސްކަލާނގެ އަޅުތަކުންގެ ތެރެއިން ތިމަންރަސްކަލާނގެ ޚިޔާރުކުރެއްވި ބަޔަކަށް، ފޮތް ވާރުތަކޮށްދެއްވީމެވެ. ފަހެ، އެއުރެންގެ އަމިއްލަ ނަފްސަށް އަނިޔާވެރިވާ ބަޔަކު، އެއުރެންގެތެރެއިން ވެއެވެ. އަދި (ހެޔޮކަންތައް ކުރުމުގައި) މެދުމިންވެ ތިބޭ މީހުން، އެއުރެންގެ ތެރެއިންވެއެވެ. އަދި ﷲގެ އިޒުނަ ފުޅާއެކު، ހެޔޮކަންތަކުގައި ކުރިއަރައިދާ މީހުން އެއުރެންގެ ތެރެއިންވެއެވެ. ބޮޑުވެގެންވާ ފަޟްލު ވަންތަކަމަކީ ހަމައެއީއެވެ.","",""],["","","","جنات عدن يدخلونها يحلون فيها من أساور من ذهب ولؤلؤا ولباسهم فيها حرير","(އެއީ) ޢަދަނެވެ ކިއުނު ސުވަރުގެތަކެވެ. އެއުރެން އެ ސުވަރުގެތަކަށް ވަންނާނެތެވެ. އެތާނގައި ރަނުންނާއި ރަންމުތުންވާ އުޅާތަކުން އެއުރެންގައި ގަހަނާ އަޅުއްވާނެތެވެ. އަދި އެތާނގައި އެއުރެންގެ ފޭރާންވާހުށީ ފަށުއިންނެވެ.","",""],["","","","وقالوا الحمد لله الذي أذهب عنا الحزن إن ربنا لغفور شكور","އަދި އެއުރެން ބުނާނެތެވެ. ހަމްދު ހުރީ ﷲއަށެވެ. އެކަލާނގެއީ، ތިމަންމެންގެ ކިބައިން ހިތާމަތައް ފިއްލެވި ރަސްކަލާނގެއެވެ. ހަމަކަށަވަރުން، ތިމަންމެންގެ ވެރިރަސްކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ގިނަގިނައިން ޝުކުރު ގަބޫލުކުރައްވާ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","الذي أحلنا دار المقامة من فضله لا يمسنا فيها نصب ولا يمسنا فيها لغوب","އެކަލާނގެއީ، އެކަލާނގެ ފަޟްލު ވަންތަކަމުން، ތިމަންމެން ގާއިމުވެ ތިބުމުގެ ގޮވަތީގައި (އެބަހީ: ސުވަރުގޭގައި) ވަޒަންވެރިކުރެއްވި ރަސްކަލާނގެއެވެ. އެތާނގައި ވަރުބަލިވުމެއް ތިމަންމެންނަކަށް ނުލިބޭނެތެވެ. އަދި އެތާނގައި ފޫހިކަމެއްވެސް ތިމަންމެންނަކަށް ނުމެލިބޭނޭމެއެވެ.","",""],["","","","والذين كفروا لهم نار جهنم لا يقضى عليهم فيموتوا ولا يخفف عنهم من عذابها كذلك نجزي كل كفور","އަދި ކާފިރު ވިމީހުންނަށް ހުރީ ނަރަކައިގެ އަލިފާނެވެ. ފަހެ، އެއުރެން މަރުވުމަކަށް، އެއުރެންގެ މައްޗަށް ނިޔާއެއް ނުކުރައްވާނެތެވެ. އަދި ނަރަކައިގެ އަޒާބުން ބައެއް، އެއުރެންގެ ކިބަޔަކުން ލުޔެއްވެސް ނުމެކުރައްވާނޭމެއެވެ. ކާފިރުވާ ކޮންމެ މީހަކަށް ތިމަންރަސްކަލާނގެ އަޒާބު ދެއްވަނީ އެފަދައިންނެވެ.","",""],["","","","وهم يصطرخون فيها ربنا أخرجنا نعمل صالحا غير الذي كنا نعمل أولم نعمركم ما يتذكر فيه من تذكر وجاءكم النذير فذوقوا فما للظالمين من نصير","އެއުރެން އެ ނަރަކައިގައި ރޮއިހޭރި ދަންނަވާނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެން ކުރަމުންގެންދިޔަ (ނުބައި) ޢަމަލު ނޫން ސާލިހު ޢަމަލުކުރުމަށް އަޅަމެން ނެރުއްވައިފާނދޭވެ! ހަނދުމަކުރާނެ މީހަކު އެދުވަސްތަކުގައި ހަނދުމަކުރާހާ ދުވަހު، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންގެ އުމުރު ނުދަންމަވަން ހެއްޔެވެ؟ އަދި އިންޒާރުކުރައްވާ ބޭކަލަކު ތިޔަބައިމީހުންގެ ގާތަށް ވަޑައިގަތެވެ. ފަހެ، ތިޔަބައިމީހުން (އަޒާބުގެ) ރަހަ ލިބިގަންނާށެވެ! ފަހެ، އަނިޔާވެރިންނަށް ނަސްރު ދޭނެ އެއްވެސް މީހަކު ނުވެތެވެ.","",""],["","","","إن الله عالم غيب السماوات والأرض إنه عليم بذات الصدور","ހަމަކަށަވަރުން، ﷲއީ، އުޑުތަކާއި، ބިމުގެ ޣައިބު ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ހިތްތަކުގައިވާހާ ކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","هو الذي جعلكم خلائف في الأرض فمن كفر فعليه كفره ولا يزيد الكافرين كفرهم عند ربهم إلا مقتا ولا يزيد الكافرين كفرهم إلا خسارا","ބިމުގައި ޚަލީފާ އިންތަކެއް ކަމުގައި ތިޔަބައިމީހުން ލެއްވީ އެކަލާނގެއެވެ. ފަހެ، ކާފިރު ވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާގެ ކާފިރު ކަން އޮތީ ހަމަ އެމީހާގެ މައްޗަށެވެ. އަދި ކާފިރުންނަށް އެއުރެން ކާފިރު ވުމުގެ ސަބަބުން، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ކޯފާމެނުވީ އިތުރެއް ނުވާނެތެވެ. އަދި ކާފިރުވި މީހުންނަށް އެއުރެންގެ ކާފިރުކަމުގެ ސަބަބުން ގެއްލުމެއް މެނުވީ އިތުރެއް ނުވާނެތެވެ.","",""],["","","","قل أرأيتم شركاءكم الذين تدعون من دون الله أروني ماذا خلقوا من الأرض أم لهم شرك في السماوات أم آتيناهم كتابا فهم على بينت منه بل إن يعد الظالمون بعضهم بعضا إلا غرورا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲ ފިޔަވައި ތިޔަބައިމީހުން އަޅުކަންކޮށްއުޅޭ ޝަރީކުންނާމެދު ނިކަން ޚަބަރު ދީ ބަލާށެވެ! އެތަކެތި ބިމުން ހެދީ ކޮންތަނެއްކަން ތިމަން ކަލޭގެފާނަށް ތިޔަބައިމީހުން ދައްކައިބަލާށެވެ! ނުވަތަ އުޑުތައް ހެއްދެވުމުގައި ބައިވެރިވުމެއް އެތަކެއްޗަށް ވަނީ ހެއްޔެވެ؟ ނުވަތަ އެއިން ކަމެއްގެ މައްޗަށް ހެތްކެއްގެ މަތީގައި އެއުރެން ވުމަށް ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ފޮތެއް ދެއްވާފައިވަނީ ހެއްޔެވެ؟ އަދި ކިއެއްތަ! އަނިޔާވެރިން އެއްބަޔަކު އަނެއްބަޔަކަށް ހެއްލުންތެރިކަމަކަށް މެނުވީ ވައުދެއް ނުކުރެތެވެ.","",""],["","","","إن الله يمسك السماوات والأرض أن تزولا ولئن زالتا إن أمسكهما من أحد من بعده إنه كان حليما غفورا","ހަމަކަށަވަރުން، ﷲ، އުޑުތަކާއި ބިން އެހުރިގޮތުން ނެއްޓިދިޔަ ނުދެއްވައި ހިފަހައްޓަވަތެވެ. އަދި ހަމަކަށަވަރުން، އެހުރިގޮތުން އެ ދެތަން ނެއްޓިއްޖެނަމަ، އެކަލާނގެ ފިޔަވައި އެތަންތަން ހިފަހައްޓާނެ އެއްވެސް މީހަކު ނުވެތެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ހަލީމްވަންތަ ގިނަގިނައިން ފާފަފުއްސަވާ ރަސްކަލާނގެ ކަމުގައިވެއެވެ.","",""],["","","","وأقسموا بالله جهد أيمانهم لئن جاءهم نذير ليكونن أهدى من إحدى الأمم فلما جاءهم نذير ما زادهم إلا نفورا","އެއުރެންގެ އެންމެގަދަ ހުވައިން ﷲ ގަންދީ އެއުރެން ހުވާކޮށް ބުނޫއެވެ. ހަމަކަށަވަރުން، އެއުރެންގެ ގާތަށް ބިރުވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު ވަޑައިގެންފިނަމަ، އެހެން ކޮންމެ އުއްމަތަކަށްވުރެން ތެދުމަގު ލިބުން ބޮޑު ބަޔަކު ކަމުގައި އެއުރެން ވާނެކަން ކަށަވަރެވެ. ފަހެ، ބިރުވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު އެއުރެންގެ ގާތަށް ވަޑައިގެންނެވިހިނދު، އެއިން ނަފުރަތުވެ، ދުރުހެލިވުން މެނުވީ، އެއުރެންނަކަށް އިތުރެއް ނުވިއެވެ.","",""],["","","","استكبارا في الأرض ومكر السيئ ولا يحيق المكر السيئ إلا بأهله فهل ينظرون إلا سنت الأولين فلن تجد لسنت الله تبديلا ولن تجد لسنت الله تحويلا","(އެއީ) ބިންމަތީގައި ބޮޑާވެގަތުމުގެ ގޮތުންނެވެ. އަދި ނުބައި މަކަރުވެރި ރޭވުމުގެ ގޮތުންނެވެ. އަދި ނުބައި މަކަރުވެރި ރޭވުން އޭގެ އަހުލުވެރިންނަށް މެނުވީ ނުޖެހޭނެތެވެ. ފަހެ، އިސްވެދިޔަ މީހުންނާމެދު، ﷲ ކަންހިންގެވިގޮތަށް މެނުވީ އެއުރެން އިންތިޒާރުކުރޭހެއްޔެވެ؟ ފަހެ، ﷲ، ކަންހިންގަވާގޮތަށް ބަދަލެއް އަންނާތީ ކަލޭގެފާނަކަށް ފެނިވަޑައެއް ނުގަންނަވާނެތެވެ. އަދި ﷲ، ކަންހިންގަވާގޮތް އެހެން ފަރާތަކަށް އަނބުރައިލެވޭތީވެސް ކަލޭގެފާނަކަށް ފެނިވަޑައެއް ނުގަންނަވާނެތެވެ.","",""],["","","","أولم يسيروا في الأرض فينظروا كيف كان عاقبة الذين من قبلهم وكانوا أشد منهم قوة وما كان الله ليعجزه من شيء في السماوات ولا في الأرض إنه كان عليما قديرا","އެއުރެން ބިމުގައި ދަތުރު ފަތުރުކޮށް، އެއުރެންގެ ކުރިން އުޅުނު މީހުންގެ ނިމުންވީ ކޮންފަދައަކުންކަން، ފަހެ، އެއުރެން ނުބަލަނީ ހެއްޔެވެ؟ އަދި އެއުރެންނަށްވުރެ (އެބަހީ: މައްކާގެ އަހުލުވެރިންނަށްވުރެން) ބާރުގަދަ ބަޔަކު ކަމުގައި އެއުރެންވޫއެވެ. އަދި އުޑުތަކުގައިވިޔަސް، ބިމުގައިވިޔަސް، ﷲ ނުކުޅައްދާނެ އެއްވެސް އެއްޗެއް ނުވެތެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ކުޅަދުންވަންތަ ކަލާނގެ ކަމުގައިވެއެވެ.","",""],["","","","ولو يؤاخذ الله الناس بما كسبوا ما ترك على ظهرها من دابة ولكن يؤخرهم إلى أجل مسمى فإذا جاء أجلهم فإن الله كان بعباده بصيرا","މީސްތަކުން ހޯދައިގަތް ފާފަތަކުގެ ސަބަބުން، ﷲ، އެއުރެންނަށް (ވަގުތުން) އުގޫބާތް ދެއްވާނަމަ، ހިނގާބިނގާއުޅޭ އެއްވެސް ދިރޭ އެއްޗެއް އެ ބިންމަތީގައި ދޫނުކުރެއްވީހެވެ. އެހެނެއްކަމަކު، ކަނޑައަޅުއްވާފައިވާ މުއްދަތަކަށް އެކަލާނގެ އެއުރެން ފަސްކުރައްވަތެވެ. ފަހެ، އެއުރެންގެ އަޖަލު އައުމުން، (އެއުރެންނަށް ޖަޒާ ދެއްވާނެތެވެ.) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، އެކަލާނގެ އަޅުތަކުންނަށް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެ ކަމުގައިވެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم يس","ى س (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","والقرآن الحكيم","ހިކުމަތް ތެރި ގުރްއާން ގަންދެއްވައި ވަހީކުރައްވަމެވެ.","",""],["","","","إنك لمن المرسلين","ހަމަކަށަވަރުން، ކަލޭގެފާނުވަނީ، ރަސޫލުންގެ ތެރެއިންކަން ކަށަވަރެވެ.","",""],["","","","على صراط مستقيم","ސީދާވެގެންވާ މަގެއްގެ މަތީގައެވެ.","",""],["","","","تنزيل العزيز الرحيم","އެ ފޮތަކީ ޢަޒީޒުވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެ ބާވައިލެއްވި ފޮތެވެ.","",""],["","","","لتنذر قوما ما أنذر آباؤهم فهم غافلون","އެއުރެންގެ ކާބަފައިންނަށް އިންޒާރުކުރައްވާފައިނުވާ ބަޔަކަށް ކަލޭގެފާނު އިންޒާރުކުރެއްވުމަށްޓަކައެވެ. ފަހެ، އެއުރެންނީ ޣާފިލު ވެގެންވާ ބަޔެކެވެ.","",""],["","","","لقد حق القول على أكثرهم فهم لا يؤمنون","ހަމަކަށަވަރުން، އެއުރެންކުރެން ގިނަމީހުންގެ މައްޗަށް ކޯފާގެ ބަސްފުޅު ހައްގު ވެއްޖެކަން ކަށަވަރެވެ. ފަހެ، އެއުރެން އީމާނެއް ނުވާނެތެވެ.","",""],["","","","إنا جعلنا في أعناقهم أغلالا فهي إلى الأذقان فهم مقمحون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެންގެ ކަނދުރާތަކުގައި ކަސްތަޅުތަކެއް ލެއްވީމެވެ. ފަހެ، އެ ކަސްތަޅުތައް ދަތްދޮޅިތަކާ ހަމަޔަށް ހުންނަހުށްޓެވެ. ފަހެ، އެއުރެންވަނީ ބޯތައް އުފުލިގެންނެވެ.","",""],["","","","وجعلنا من بين أيديهم سدا ومن خلفهم سدا فأغشيناهم فهم لا يبصرون","އަދި ތިމަންރަސްކަލާނގެ އެއުރެންގެ ކުރިމަތިން ހުރަހަކާއި، އެއުރެންގެ ފުރަގަހުން ހުރަހެއް ލެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އެއުރެންގެ ލޯތަކުގައި ފަރުދާއެއް ލެއްވީމެވެ. ދެން އެއުރެންނަކަށް ނުފެންނާނެތެވެ.","",""],["","","","وسواء عليهم أأنذرتهم أم لم تنذرهم لا يؤمنون","އަދި ކަލޭގެފާނު އެއުރެންނަށް އިންޒާރުކުރެއްވިޔަސް ނުވަތަ އެއުރެންނަށް ކަލޭގެފާނު އިންޒާރު ނުކުރެއްވިޔަސް، އެއުރެންނަށް ހަމަހަމަވެގެންވެއެވެ. އެއުރެން އީމާނެއް ނުވާނެތެވެ.","",""],["","","","إنما تنذر من اتبع الذكر وخشي الرحمن بالغيب فبشره بمغفرة وأجر كريم","ކަލޭގެފާނު އިންޒާރުކުރައްވާކަން ކަށަވަރީ، ގުރްއާނަށް ތަބާވެ، ޣައިބުގައި ރަޙްމާންވަންތަ ރަސްކަލާނގެއަށް ބިރުވެތިވާ މީހާއަށެވެ. ފަހެ، އެމީހާއަށް ފާފަފުއްސެވުމާއި، ދީލަތި ދަރުމައެއް ހުރިކަމުގެ އުފާވެރި ޚަބަރު ކަލޭގެފާނު ދެއްވާށެވެ!","",""],["","","","إنا نحن نحيي الموتى ونكتب ما قدموا وآثارهم وكل شيء أحصيناه في إمام مبين","ހަމަކަށަވަރުން، މަރުވެފައިވާ މީހުން އަލުން ދިރުއްވަނީ ތިމަންރަސްކަލާނގެއެވެ. އަދި އެއުރެން އިސްކޮށްފައިވާ ޢަމަލު ތަކާއި އެއުރެންގެ ފަހަށް ދޫކޮށްފައި ދިޔަ އަޘަރުތައް ތިމަންރަސްކަލާނގެ ލިޔުއްވަމެވެ. އަދި ކޮންމެ ކަމެއްމެ ބަޔާންވެގެންވާ ފޮތެއްގައި ތިމަންރަސްކަލާނގެ ހިމެނުއްވީމެވެ.","",""],["","","","واضرب لهم مثلا أصحاب القرية إذ جاءها المرسلون","ރަށެއްގެ އަހުލުވެރިންގެ ވާހަކަ މިސާލެއްގެ ގޮތުގައި، ކަލޭގެފާނު އެއުރެންނަށް ކިޔައިދެއްވާށެވެ! (އެއީ) އެއުރެންގެ ގާތަށް ރަސޫލުން ވަޑައިގަތްހިނދުގައެވެ.","",""],["","","","إذ أرسلنا إليهم اثنين فكذبوهما فعززنا بثالث فقالوا إنا إليكم مرسلون","ތިމަންރަސްކަލާނގެ އެއުރެންގެ ގާތަށް ދެ ރަސޫލުން ފޮނުއްވިހިނދެވެ. ފަހެ، އެއުރެން އެ ދެބޭކަލުން ދޮގުކުޅައޫއެވެ. ދެން ތިންވަނަ ބޭކަލަކު ފޮނުއްވުމުން، އެ ދެބޭކަލުންނަށް ގަދަކަން ދެއްވީމެވެ. ފަހެ، އެބޭކަލުން ވިދާޅުވޫއެވެ. ހަމަކަށަވަރުން، ތިމަންމެންނީ، ތިޔަބައިމީހުންގެ ގާތަށް ފޮނުއްވާފައިވާ ރަސޫލުންނެވެ.","",""],["","","","قالوا ما أنتم إلا بشر مثلنا وما أنزل الرحمن من شيء إن أنتم إلا تكذبون","އެއުރެން ބުނޫއެވެ. ތިމަންމެންފަދަ އާދަމުގެދަރިން ކަމުގައި މެނުވީ ތިޔަބޭކަލުން ނުވަމުއެވެ. އަދި ރަޙްމާންވަންތަ ރަސްކަލާނގެ އެއްވެސް އެއްޗެއް ބާވައެއް ނުލައްވަތެވެ. ދޮގުހަދާ ބަޔަކުކަމުގައި މެނުވީ ތިޔަބޭކަލުން ނުވަމުއެވެ.","",""],["","","","قالوا ربنا يعلم إنا إليكم لمرسلون","އެބޭކަލުން ވިދާޅުވޫއެވެ. ހަމަކަށަވަރުން، ތިމަންމެންނީ ތިޔަބައިމީހުންގެ ގާތަށް ފޮނުއްވާފައިވާ ރަސޫލު ންކަން، ތިމަންމެންގެ ވެރިރަސްކަލާނގެ ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","وما علينا إلا البلاغ المبين","އަދި ބަޔާން ވެގެންވާ އިއްވުން މެނުވީ، ތިމަންމެންގެ މައްޗަކަށް ނުވެއެވެ.","",""],["","","","قالوا إنا تطيرنا بكم لئن لم تنتهوا لنرجمنكم وليمسنكم منا عذاب أليم","އެއުރެން ބުނޫއެވެ. ހަމަކަށަވަރުން، ތިޔަބޭކަލުންގެ ސަބަބުން ތިމަންމެންނަށް ސުންޕާކަން ލިބިއްޖެއެވެ. ތިޔަބޭކަލުން ތިޔަކަން ހުއްޓައިނުލެއްވިނަމަ ތިމަންމެން ތިޔަބޭކަލުން ރަޖަމްކުރާހުށީމުއެވެ. ހަމަކަށަވަރުން، ތިމަންމެންގެ ކިބައިން ތިޔަބޭކަލުންނަށް ވޭންދެނިވި އުގޫބާތް ލިބިދާހުށިކަން ކަށަވަރެވެ.","",""],["","","","قالوا طائركم معكم أئن ذكرتم بل أنتم قوم مسرفون","އެބޭކަލުން ވިދާޅުވޫއެވެ. ތިޔަބައިމީހުންގެ ސުންޕާކަންވަނީ ތިޔަބައިމީހުންނާ އެކުގައެވެ. ތިޔަބައިމީހުންނަށް (ހައްގު ގޮތް) ހަނދާންކޮށްދެވުނަސް (އެއީ، ސުންޕާކަމެއް ކަމުގައި ބަލަނީ) ހެއްޔެވެ؟ އަދި ކިއެއްތަ! ތިޔަބައިމީހުންނީ (ކާފިރުކަމުގައި) ހައްދުފަހަނަޅައިފައިވާ ބަޔެކެވެ.","",""],["","","","وجاء من أقصى المدينة رجل يسعى قال يا قوم اتبعوا المرسلين","އެރަށުގެ އެންމެ ދުރުފަރާތުން މީހަކު ދުވަމުން އައިސް ބުންޏެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން އެ ރަސޫލުންނަށް ތަބާ ވާށެވެ!","",""],["","","","اتبعوا من لا يسألكم أجرا وهم مهتدون","ތިޔަބައިމީހުންގެ ކިބައިން، އެއްވެސް އުޖޫރައަކަށް ނޭދޭބަޔަކަށް ތިޔަބައިމީހުން ތަބާ ވާށެވެ! އަދި އެއުރެންނީ ތެދުމަގު ލިބިގެންވާ ބަޔެކެވެ.","",""],["","","","وما لي لا أعبد الذي فطرني وإليه ترجعون","އަދި އިސްވެދިޔަ މިސާލަކާ ނުލައި، ތިމަން އުފެއްދެވި ކަލާނގެއަށް ތިމަން އަޅުކަން ނުކުރަންވީ ކީއްވެގެން ހެއްޔެވެ؟ އަދި ތިޔަބައިމީހުން ރުޖޫއަކުރައްވާހުށީ އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","أأتخذ من دونه آلهة إن يردن الرحمن بضر لا تغن عني شفاعتهم شيئا ولا ينقذون","އެކަލާނގެ ފިޔަވައި އެހެން އިލާހުންތަކެއް ތިމަން ހިފަންވީ ހެއްޔެވެ؟ ރަޙްމާންވަންތަ ރަސްކަލާނގެ، ތިމަންނާއަށް ގެއްލުމަކަށް އިރާދަކުރައްވާނަމަ، އެތަކެތީގެ ޝަފާއަތް ތެރިކަމުން ތިމަންނާއަށް އެއްވެސްކަމެއް ފުއްދައެއް ނުދެވޭނެތެވެ. އަދި އެތަކެއްޗަށް ތިމަން ސަލާމަތެއްވެސް ނުމެކުރެވޭނޭމެއެވެ.","",""],["","","","إني إذا لفي ضلال مبين","އެހެންވެއްޖެނަމަ، ހަމަކަށަވަރުން، ތިމަންވާހުށީ ފާޅުވެގެންވާ މަގުފުރެދުމެއްގައިކަން ކަށަވަރެވެ.","",""],["","","","إني آمنت بربكم فاسمعون","ހަމަކަށަވަރުން، ތިމަން ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއަށް އީމާން ވެއްޖައީމެވެ. ފަހެ، ތިޔަބައިމީހުން ތިމަންގެ ބަސްއަހާށެވެ!","",""],["","","","قيل ادخل الجنة قال يا ليت قومي يعلمون","އަންގަވާނެތެވެ. ތިބާ ސުވަރުގެއަށް ވަންނާށެވެ! އޭނާ ބުނާނެތެވެ. ތިމަންގެ ވެރިރަސްކަލާނގެ ތިމަންނާއަށް ފާފަފުއްސަވައި، މާތްކުރައްވާފައިވާ މީހުންގެ ތެރެއިން، އެކަލާނގެ ތިމަން ލެއްވިގޮތް، ތިމަންގެ ގައުމުގެމީހުން ދަންނާނެނަމަ ކިހާރަނގަޅުހެއްޔެވެ؟","",""],["","","","بما غفر لي ربي وجعلني من المكرمين","އަންގަވާނެތެވެ. ތިބާ ސުވަރުގެއަށް ވަންނާށެވެ! އޭނާ ބުނާނެތެވެ. ތިމަންގެ ވެރިރަސްކަލާނގެ ތިމަންނާއަށް ފާފަފުއްސަވައި، މާތްކުރައްވާފައިވާ މީހުންގެ ތެރެއިން، އެކަލާނގެ ތިމަން ލެއްވިގޮތް، ތިމަންގެ ގައުމުގެމީހުން ދަންނާނެނަމަ ކިހާރަނގަޅުހެއްޔެވެ؟","",""],["","","","وما أنزلنا على قومه من بعده من جند من السماء وما كنا منزلين","އޭނާއަށްފަހު، ތިމަންރަސްކަލާނގެ އޭނާގެ ގައުމުގެމީހުންގެ މައްޗަށް އުޑުން (މަލާއިކަތުންގެ) ލަޝްކަރެއް ބާވައެއް ނުލައްވަމެވެ. އަދި ތިމަންރަސްކަލާނގެ (އެފަދަ ލަޝްކަރެއް) ބާވައިލައްވާކަށް އިރާދައެއް ނުކުރައްވަމެވެ.","",""],["","","","إن كانت إلا صيحة واحدة فإذا هم خامدون","އެއުރެންގެ އުގޫބާތަކީ ބިރުވެރި އެންމެ އަޑެއް ކަމުގައި މެނުވީ ނުވެއެވެ. ފަހެ، އެހާރުން، މަރުވެ ހިމޭންވެފައިވާ ބަޔަކު ކަމުގައި އެއުރެންވޫއެވެ.","",""],["","","","يا حسرة على العباد ما يأتيهم من رسول إلا كانوا به يستهزئون","އަޅުތަކުންގެ މައްޗަށްހުރި ހިތާމައެއްގެ ބޮޑުކަމާއެވެ! އެބޭކަލަކަށް އެއުރެން ފުރައްސާރަކުރާގޮތުގައި މެނުވީ، އެއުރެންގެ ގާތަށް އެއްވެސް ރަސޫލަކު ވަޑައެއްނުގަންނަވަތެވެ.","",""],["","","","ألم يروا كم أهلكنا قبلهم من القرون أنهم إليهم لا يرجعون","އެއުރެންގެ ކުރިން ތިމަންރަސްކަލާނގެ، ކިތައްކިތައް އުއްމަތް ހަލާކުކުރެއްވިކަން އެއުރެންނަށް ނޭނގޭހެއްޔެވެ؟ ހަމަކަށަވަރުން، އެއުރެން އެއުރެންގެ ގާތަށް އެނބުރިއެއް ނާންނާނެތެވެ.","",""],["","","","وإن كل لما جميع لدينا محضرون","އަދި އެއެންމެންނީ (ގިޔާމަތް ދުވަހުން) ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ޙާޒިރުުކުރައްވާނެ ބަޔަކުކަމުގައި ނޫނީ ނުވެއެވެ.","",""],["","","","وآية لهم الأرض الميتة أحييناها وأخرجنا منها حبا فمنه يأكلون","އަދި މަރުވެފައިވާ ބިމަކީ، އެއުރެންނަށްޓަކައި (އަލުން ދިރުމަކަށް ފޮނުއްވާނޭކަމުގެ) ހެތްކެކެވެ. ތިމަންރަސްކަލާނގެ އެ ބިންގަނޑު ދިރުއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އެ ބިމުން އޮށްޓަރު ނެރުއްވީމެވެ. ފަހެ، އެއުރެން ކައިއުޅެނީ އެއިންނެވެ.","",""],["","","","وجعلنا فيها جنات من نخيل وأعناب وفجرنا فيها من العيون","އަދި ކަދުރުރުއްތަކާއި، މޭބިސްކަދުރުގެ ބަގީޗާތައް ތިމަންރަސްކަލާނގެ އެ ބިމުގައި ލެއްވީމެވެ. އަދި ފެންއާރުތައް އެބިމުގައި ހިންގެވީމެވެ.","",""],["","","","ليأكلوا من ثمره وما عملته أيديهم أفلا يشكرون","(އެއީ) އެތާނގެ މޭވާއިންނާއި، އެއުރެންގެ އަތްތަކުން މަސައްކަތްކޮށްގެން ހޯދިތަކެތިން އެއުރެން ކައިއުޅުމަށްޓަކައެވެ. ފަހެ، އެއުރެން ޝުކުރު ނުކުރަނީ ހެއްޔެވެ؟","",""],["","","","سبحان الذي خلق الأزواج كلها مما تنبت الأرض ومن أنفسهم ومما لا يعلمون","ބިމުން ފަޅައިގެންހެދޭ ތަކެތީގެ ތެރެއިންނާއި، އެއުރެންގެ އަމިއްލަ ނަފްސު ތަކުންނާއި، އެއުރެން ނުދަންނަ ތަކެތިން، ޖޯޑުޖޯޑަށް ހުރިހާ ތަކެތި ހެއްދެވި ރަސްކަލާނގެ ހުސްތާހިރުވަންތަ ކަމާއެވެ!","",""],["","","","وآية لهم الليل نسلخ منه النهار فإذا هم مظلمون","ރޭގަނޑަކީ، އެއުރެންނަށްހުރި ހެތްކެކެވެ. ތިމަންރަސްކަލާނގެ ރޭގަނޑުގެ ތެރެއިން ދުވާލު ވަކިކުރައްވަމެވެ. ފަހެ، އެހާރުން އެއުރެން އަނދިރީގެ ތެރޭގައިވެއެވެ.","",""],["","","","والشمس تجري لمستقر لها ذلك تقدير العزيز العليم","އަދި އިރު، އެއަށް ކަނޑައެޅި ގަރާރު ވަނިވި ތަނަކަށް ދާނދެން ހިނގަހިގާ ހުރެތެވެ. އެއީ ޢަޒީޒުވަންތަ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެ މިންވަރުކުރައްވާފައިވާ ގޮތެވެ.","",""],["","","","والقمر قدرناه منازل حتى عاد كالعرجون القديم","އަދި ހަނދަށް ތިމަންރަސްކަލާނގެ މަންޒިލް ތަކެއް މިންވަރު ކުރެއްވީމެވެ. ދުވަސްވެ، ހިކި، ގުދުވެފައިވާ އިހާގޮނޑިއެއް ފަދައިން އެނބުރި އަތުވެއްޖައުމަށް ދާނދެނެވެ. (އެބަހީ: ހުޅެވިހަނދަކަށް ބަދަލުވެއްޖައުމަށް ދާނދެނެވެ.)","",""],["","","","لا الشمس ينبغي لها أن تدرك القمر ولا الليل سابق النهار وكل في فلك يسبحون","ހަނދު އަތުލައިގަތުމަކީ، އިރަށް އެކަށީގެންވާ ކަމެއްނޫނެވެ. އަދި ދުވާލަށްވުރެ ރޭގަނޑު ކުރިއަރައި ދާކަމަކަށްވެސް ނުމެވޭމެއެވެ. އަދި އެއިން ކޮންމެ އެއްޗެއްމެ ފަލަކެއްގައި ހިނގަހިނގާ ހުރެތެވެ.","",""],["","","","وآية لهم أنا حملنا ذريتهم في الفلك المشحون","އެއުރެންނަށް ހެތްކެއްވެއެވެ. އެއީ ހަމަކަށަވަރުން، ބަރާވެގެންވާ ނަވުގައި ތިމަންރަސްކަލާނގެ އެއުރެންގެ ދަރިފަސްކޮޅު އުފުއްލަވައިދެއްވިކަމެވެ.","",""],["","","","وخلقنا لهم من مثله ما يركبون","އަދި އެފަދަ ތަކެތިން، އެއުރެން އަރައިގެން ދުއްވާނެ ތަކެތި އެއުރެންނަށްޓަކައި ތިމަންރަސްކަލާނގެ ހައްދަވައިދެއްވީމެވެ.","",""],["","","","وإن نشأ نغرقهم فلا صريخ لهم ولا هم ينقذون","އަދި ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާނަމަ، އެއުރެން ޣަރަގުކުރައްވައިފާހުށީމެވެ. ފަހެ، އެހިނދު، އެއުރެންނަށް އެހީވާނެ ފަރާތެއް ނުވެއެވެ. އަދި ސަލާމަތްކުރައްވާނޭ ބަޔަކުކަމުގައި އެއުރެން ނުމެވޭމެއެވެ.","",""],["","","","إلا رحمة منا ومتاعا إلى حين","ތިމަންރަސްކަލާނގެ ހަޒުރަތުން އައި ރަހުމަތެއްގެ ގޮތުގައްޔާއި، ކަނޑައަޅުއްވާފައިވާ މުއްދަތަކާ ޖެހެންދެން، ދެއްވާ، ދުނިޔޭގެ ވަގުތީ އުފަލެއްގެ ގޮތުގައި މެނުވީއެވެ.","",""],["","","","وإذا قيل لهم اتقوا ما بين أيديكم وما خلفكم لعلكم ترحمون","އަދި ތިޔަބައިމީހުންނަށް ރަހުމަތް ލެއްވުމަށްޓަކައި، ތިޔަބައިމީހުންގެ ކުރިމަތީގައިވާ ތަނާއި، ތިޔަބައިމީހުންގެ ފަހަތުގައިވާ ތަނަށް ބިރުވެތިވެ ރައްކާތެރިވާށޭ އެއުރެންނަށް އަންގަވައިފިނަމަ، އެއުރެން ފުރަގަސްދީ އެނބުރިދެތެވެ.","",""],["","","","وما تأتيهم من آية من آيات ربهم إلا كانوا عنها معرضين","އަދި އެ އާޔަތްތަކަށް އެއުރެން ފުރަގަސްދޭކަމުގައިވި އާޔަތެއް މެނުވީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ އާޔަތްތަކުގެ ތެރެއިން އެއްވެސް އާޔަތެއް އެއުރެންގެ ގާތަކަށް ނާދެތެވެ.","",""],["","","","وإذا قيل لهم أنفقوا مما رزقكم الله قال الذين كفروا للذين آمنوا أنطعم من لو يشاء الله أطعمه إن أنتم إلا في ضلال مبين","އަދި ތިޔަބައިމީހުންނަށް ﷲ ދެއްވާފައިވާ ތަކެތިން ހޭދަކޮށްއުޅޭށޭ އެއުރެންނަށް އަންގަވައިފިނަމަ، ކާފިރުވި މީހުން، އީމާންވި މީހުންނަށް ބުނެތެވެ. ﷲ އިރާދަކުރައްވާނަމަ، އެމީހަކަށް ކާންދެއްވާނެ މީހަކަށް، ތިމަންމެން ކާންދޭންވީހެއްޔެވެ؟ ފާޅުވެގެންވާ މަގުފުރެދުމެއްގައި މެނުވީ ތިޔަބައިމީހުން ނުވަމުއެވެ.","",""],["","","","ويقولون متى هذا الوعد إن كنتم صادقين","އެއުރެން ބުނެތެވެ. ތިޔަބައިމީހުންނީ، ތެދުބުނާ ބަޔަކު ކަމުގައިވާނަމަ، ތިޔަ (ބުނާ އަޒާބުގެ) ވައުދު އަންނާނީ ކޮންއިރަކުން ހެއްޔެވެ؟","",""],["","","","ما ينظرون إلا صيحة واحدة تأخذهم وهم يخصمون","ބިރުވެރި އެންމެ އަޑަކަށް މެނުވީ، އެއުރެން އިންތިޒާރެއް ނުކުރެތެވެ. އެއުރެން އެކަކު އަނެކަކާ ދެކޮޅުވެރިވޭވެ ތިއްބައި، އެ އަޑު (އައިސް) އެއުރެން ގެންދާނެތެވެ.","",""],["","","","فلا يستطيعون توصية ولا إلى أهلهم يرجعون","ފަހެ (އެހިނދު) އެއްވެސް ވަސިއްޔަތެއް ކުރާކަށް އެއުރެންނަކަށް ކުޅަދާނައެއް ނުވާނެތެވެ. އަދި އެއުރެންގެ އަހުލުވެރިންގެ ގާތަކަށް އެއުރެން އެނބުރި ނުމެއަންނާނޭމެއެވެ.","",""],["","","","ونفخ في الصور فإذا هم من الأجداث إلى ربهم ينسلون","އަދި ތާޅަފިލި ފުމެލައްވާހުއްޓެވެ. ފަހެ، އެހާރުން އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ކަށްވަޅުތަކުން އަވަސްއަވަހަށް ނުކުމެގެންދާނެތެވެ.","",""],["","","","قالوا يا ويلنا من بعثنا من مرقدنا هذا ما وعد الرحمن وصدق المرسلون","އެއުރެން ބުނާނެތެވެ. އޭ ތިމަންމެންނަށްހުރި ހަލާކެއްގެ ބޮޑުކަމާއެވެ! ތިމަންމެން ނިދަންތިބިތަނުން، އަލުން ދިރުމަކަށް ފޮނުއްވީ ކާކުހެއްޔެވެ؟ މިއީ ރަޙްމާންވަންތަ ރަސްކަލާނގެ ވައުދުކުރެއްވި ކަންތަކެވެ. އަދި ރަސޫލުން ވިދާޅުވި ތެދުބަސްފުޅެވެ.","",""],["","","","إن كانت إلا صيحة واحدة فإذا هم جميع لدينا محضرون","ބިރުވެރި އެންމެ އަޑެއްކަމުގައި މެނުވީ އެކަންތައް ނުވެއެވެ. ފަހެ، އެހާރުން އެއުރެން އެންމެންވާހުށީ ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް ޙާޒިރުުކުރައްވާފައެވެ.","",""],["","","","فاليوم لا تظلم نفس شيئا ولا تجزون إلا ما كنتم تعملون","ފަހެ، މިއަދު އެއްވެސް ނަފްސަކަށް އެއްވެސް ކަމަކުން ބޭއިންސާފެއް ނުކުރައްވާނެތެވެ. އަދި ތިޔަބައިމީހުން ކޮށްއުޅުނު ޢަމަލަށް މެނުވީ ތިޔަބައިމީހުންނަށް ޖަޒާއެއް ނުދެއްވާނެތެވެ.","",""],["","","","إن أصحاب الجنة اليوم في شغل فاكهون","ހަމަކަށަވަރުން، ސުވަރުގޭގެ އަހުލުވެރިން މިއަދުވަނީ، އުފާ ފާގަތިކަންމަތީ މަޝްޣޫލު ވެގެންނެވެ.","",""],["","","","هم وأزواجهم في ظلال على الأرائك متكئون","އެއުރެންނާއި އެއުރެންގެ އަނބިންވަނީ، ހިޔަލުގައި ދާންތަކުގެމަތީ ލެނގިލައިގެންނެވެ.","",""],["","","","لهم فيها فاكهة ولهم ما يدعون","އެއުރެންނަށް އެތާނގައި މޭވާތައްވެއެވެ. އަދި އެއުރެން އެދޭ (ހުރިހާ) ކަމެއް އެއުރެންނަށް (އެތާނގައި) ވެއެވެ.","",""],["","","","سلام قولا من رب رحيم","ރަޙީމްވަންތަ ކަލެއްގެ ހަޒުރަތުން އިއްވަވާ ސަލާމްގެ ބަސްފުޅެވެ.","",""],["","","","وامتازوا اليوم أيها المجرمون","އޭ ކުށްވެރިންނޭވެ! މިއަދު ތިޔަބައިމީހުން (މުއުމިނުންނާ) ވަކިވާށެވެ!","",""],["","","","ألم أعهد إليكم يا بني آدم أن لا تعبدوا الشيطان إنه لكم عدو مبين","އޭ އާދަމުގެދަރިންނޭވެ! ތިޔަބައިމީހުން ޝައިތާނާއަށް އަޅުކަން ނުކުރުމަށް ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް އަމުރުނުކުރައްވަން ހެއްޔެވެ؟ ހަމަކަށަވަރުން، އޭނާޔަކީ ތިޔަބައިމީހުންނަށްހުރި، ފާޅުވެގެންވާ އަދާވަތް ތެރިޔެކެވެ.","",""],["","","","وأن اعبدوني هذا صراط مستقيم","އަދި ތިޔަބައިމީހުން ތިމަންރަސްކަލާނގެއަށް އަޅުކަންކުރާށެވެ! މިއީ ސީދާވެގެންވާ ތެދުމަގެވެ.","",""],["","","","ولقد أضل منكم جبلا كثيرا أفلم تكونوا تعقلون","އަދި ހަމަކަށަވަރުން، އެ ޝައިތާނާ ތިޔަބައިމީހުންގެ ތެރެއިން ގިނަބަޔަކު މަގުފުރައްދައިފިއެވެ. ފަހެ، ވިސްނާ ބަޔަކުކަމުގައި ތިޔަބައިމީހުން ނުވަމުހެއްޔެވެ؟","",""],["","","","هذه جهنم التي كنتم توعدون","މިއީ ތިޔަބައިމީހުންނަށް ވައުދުކުރައްވާފައިވާ ނަރަކައެވެ.","",""],["","","","اصلوها اليوم بما كنتم تكفرون","ތިޔަބައިމީހުން ކާފިރުވެ އުޅުނުކަމުގެ ސަބަބުން، މިއަދު ތިޔަބައިމީހުން އެ ނަރަކަޔަށް ވަންނާށެވެ!","",""],["","","","اليوم نختم على أفواههم وتكلمنا أيديهم وتشهد أرجلهم بما كانوا يكسبون","މިއަދު ތިމަންރަސްކަލާނގެ އެއުރެންގެ އަނގަތަކުގައި ސިއްކަގައްސަވައި ބަންދުކުރައްވާހުށީމެވެ. އަދި އެއުރެންގެ އަތްތައް ތިމަންރަސްކަލާނގެއަށް ބަސް ދަންނަވާނެތެވެ. އަދި އެއުރެން ހޯދައިއުޅުނު ޢަމަލު ތަކާމެދު އެއުރެންގެ ފައިތައް ހެކިދޭނެތެވެ.","",""],["","","","ولو نشاء لطمسنا على أعينهم فاستبقوا الصراط فأنى يبصرون","އަދި ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާނަމަ، އެއުރެންގެ ލޯތައް ކަނުކުރައްވައިފީމުހެވެ. ފަހެ، އެއުރެން މަގުން ދިއުމަށް އަވަސްވެގަންނާނެތެވެ. ފަހެ (އެހިނދު) އެއުރެންނަށް ފެންނާނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","ولو نشاء لمسخناهم على مكانتهم فما استطاعوا مضيا ولا يرجعون","އަދި ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާނަމަ، އެއުރެން ތިބިތާ ތިއްބައި އެއުރެންގެ ސިފަ ބަދަލުކުރައްވައިފީމުހެވެ. ފަހެ (އެހިނދު) ކުރިޔަށް ދިޔުމަކަށްވެސް އަދި ފަހަށް އެނބުރި އައުމަކަށްވެސް، އެއުރެންނަކަށް ކުޅަދާނަވެގެނެއް ނުވެތެވެ.","",""],["","","","ومن نعمره ننكسه في الخلق أفلا يعقلون","ތިމަންރަސްކަލާނގެ އެމީހެއްގެ އުމުރު ދިގުކުރައްވާ މީހާ (ގެ ކަންތައް) ހެއްދެވި ހެއްދެވުމުގައި އެކޮޅުކޮޅުން ޖައްސަވާހުށީމެވެ. (އެބަހީ: އާރެއް ބާރެއްނެތް ގޮތުގައި ފެށިގެންއައިސް ޒުވާންކަމުގެ ދައުރު ނިމި، އެންމެފަހުން އާރެއް ބާރެއް ނެތް މީހަކު ކަމުގައި ލައްވާހުށީމެވެ.) ފަހެ، އެއުރެން ނުވިސްނަނީ ހެއްޔެވެ؟","",""],["","","","وما علمناه الشعر وما ينبغي له إن هو إلا ذكر وقرآن مبين","އަދި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ޅެން އުނގަންނަވައެއް ނުދެއްވަމެވެ. އަދި އެކަލޭގެފާނު އެކަމަކަށް އެކަށީގެނެއްވެސް ނުވެތެވެ. އެއީ ހަނދާންކޮށްދެނިވި ފޮތެއް ކަމުގައްޔާއި، ބަޔާންވެގެންވާ ގުރްއާންކަމުގައި މެނުވީ ނުވެއެވެ.","",""],["","","","لينذر من كان حيا ويحق القول على الكافرين","އެއީ ދިރިހުރި ކަމުގައިވާ މީހަކަށް އިންޒާރުކުރެއްވުމަށްޓަކައެވެ. އަދި ކާފިރުންގެ މައްޗަށް (އަޒާބުގެ) ބަސްފުޅު ހައްގު ވުމަށްޓަކައެވެ.","",""],["","","","أولم يروا أنا خلقنا لهم مما عملت أيدينا أنعاما فهم لها مالكون","ތިމަންރަސްކަލާނގެ އަތްޕުޅުން ހެއްދެވި ތަކެތީގެ ތެރެއިން ނަޢަމް ސޫފި، އެއުރެންނަށްޓަކައި ހައްދަވާފައިވާތީ، އެއުރެންނަކަށް ނުފެނޭހެއްޔެވެ؟ ފަހެ، އެއުރެންނީ އެ ތަކެތީގެ މިލްކުވެރިންނެވެ.","",""],["","","","وذللناها لهم فمنها ركوبهم ومنها يأكلون","އަދި ތިމަންރަސްކަލާނގެ އެތަކެތި އެއުރެންނަށް ކިޔަމަންކޮށްދެއްވީމެވެ. ފަހެ، އޭގެތެރެއިން އެއުރެންގެ ސަވާރީތައްވެއެވެ. އަދި އެއުރެން އެ ތަކެތިން ކައި އުޅެތެވެ.","",""],["","","","ولهم فيها منافع ومشارب أفلا يشكرون","އަދި މަންފާތަކާއި، ބުއިންތައް އެ ތަކެތީގައި އެއުރެންނަށްޓަކައިވެއެވެ. ފަހެ، އެއުރެން ޝުކުރު ނުކުރަނީ ހެއްޔެވެ؟","",""],["","","","واتخذوا من دون الله آلهة لعلهم ينصرون","އަދި އެއުރެންނަށް ނަސްރު ލިބޭތޯ ﷲ ފިޔަވައި އެހެން އިލާހުންތަކެއް ހިފިއެވެ.","",""],["","","","لا يستطيعون نصرهم وهم لهم جند محضرون","އެތަކެއްޗަކަށް އެއުރެންނަށް ނަސްރު ދިނުމަކަށް ކުޅަދާނަވެގެނެއް ނުވެތެވެ. އެތަކެއްޗަށް (ޚިދުމަތްކުރުމުގައި) ޙާޒިރުުކުރައްވާފައިވާ ލަޝްކަރެއް ކަމުގައި އެއުރެންވާ ޙާލު ގައެވެ.","",""],["","","","فلا يحزنك قولهم إنا نعلم ما يسرون وما يعلنون","ފަހެ، އެއުރެން ދައްކާ ވާހަކަ ކަލޭގެފާނު ހިތާމަވެރިކުރުވިޔަ ނުދެއްވާށެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެން ސިއްރުކުރާ ކަންތަކާއި، ފާޅުކުރާ ކަންތައް ދެނެވޮޑިގެންވަމެވެ.","",""],["","","","أولم ير الإنسان أنا خلقناه من نطفة فإذا هو خصيم مبين","ހަމަކަށަވަރުން، މަނިތިއްކަކުން ތިމަންރަސްކަލާނގެ އިންސާނާ ހެއްދެވިކަން، އެ އިންސާނާއަށް ނޭނގެނީ ހެއްޔެވެ؟ ފަހެ، އެހާރުން އޭނާވަނީ ފާޅުވެ ބަޔާންވެގެންވާ ދެކޮޅުވެރިޔަކު ކަމުގައެވެ.","",""],["","","","وضرب لنا مثلا ونسي خلقه قال من يحيي العظام وهي رميم","އަދި އެ އިންސާނާ ތިމަންރަސްކަލާނގެއަށް މިސާލެއް ޖެއްސެވެ. އަދި އޭނާ ހެއްދެވިގޮތް އޭނާ ހަނދުމަނައްތައިލީއެވެ. އޭނާ ބުންޏެވެ. ކަށިތައް ފީވެ، ހަލާކުވެފައިވަނިކޮށް، އެތަކެތި ދިރުއްވާނީ ކާކުހެއްޔެވެ؟","",""],["","","","قل يحييها الذي أنشأها أول مرة وهو بكل خلق عليم","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެ ކަށިތައް އަލުން ދިރުއްވާނީ، ފުރަތަފަހަރު އެކަށިތައް އުފެއްދެވި ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެއީ، ހުރިހާ މަޚްލޫގުންގެ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","الذي جعل لكم من الشجر الأخضر نارا فإذا أنتم منه توقدون","އެކަލާނގެއީ، ފެހިކުލައިގެ ގަހުން ތިޔަބައިމީހުންނަށްޓަކައި އަލިފާންލެއްވި ރަސްކަލާނގެއެވެ. ފަހެ، އެހާރުން ތިޔަބައިމީހުން އެ ގަސްގަހުން އަލިފާން ރޯކޮށް އުޅެމުއެވެ.","",""],["","","","أوليس الذي خلق السماوات والأرض بقادر على أن يخلق مثلهم بلى وهو الخلاق العليم","އެއުރެންފަދަ ބަޔަކު ހެއްދެވުމަށް އުޑުތަކާއި ބިން ހެއްދެވި ރަސްކަލާނގެ ކުޅަދުންވަންތަވެވޮޑިގެން ނުވޭހެއްޔެވެ؟ ނޫނެކެވެ! އެކަލާނގެއީ، އެންމެހާ ތަކެތި ހައްދަވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","إنما أمره إذا أراد شيئا أن يقول له كن فيكون","އެކަލާނގެ ކަމަކަށް އިރާދަކުރައްވައިފިނަމަ، އެކަލާނގެ އަމުރު ފުޅުވާކަން ކަށަވަރީ އެކަމަކަށް، [ވާށޭ] ވަހީކުރެއްވުމެވެ. ދެން އެކަމެއް ވެދެތެވެ.","",""],["","","","فسبحان الذي بيده ملكوت كل شيء وإليه ترجعون","ފަހެ، އެކަލާނގެ އަތްޕުޅުގައި އެންމެހާ ކަންތަކުގެ އެންމެމަތީ ވެރިކަންވާ ރަސްކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! އަދި ތިޔަބައިމީހުން ރުޖޫއަކުރައްވާހުށީ އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","بسم الله الرحمن الرحيم والصافات صفا","ސަފުސަފަށް ތިއްބަވާ މަލާއިކަތްނާއި، އުރެދުންތަކުން މީސްތަކުން ދުރުކުރައްވާ މަލާއިކަތްނާއި، ގުރްއާން ކިޔަވައިވިދާޅުވާ މަލާއިކަތުން ގަންދެއްވައި ވަހީކުރައްވަމެވެ.","",""],["","","","فالزاجرات زجرا","ސަފުސަފަށް ތިއްބަވާ މަލާއިކަތްނާއި، އުރެދުންތަކުން މީސްތަކުން ދުރުކުރައްވާ މަލާއިކަތްނާއި، ގުރްއާން ކިޔަވައިވިދާޅުވާ މަލާއިކަތުން ގަންދެއްވައި ވަހީކުރައްވަމެވެ.","",""],["","","","فالتاليات ذكرا","ސަފުސަފަށް ތިއްބަވާ މަލާއިކަތްނާއި، އުރެދުންތަކުން މީސްތަކުން ދުރުކުރައްވާ މަލާއިކަތްނާއި، ގުރްއާން ކިޔަވައިވިދާޅުވާ މަލާއިކަތުން ގަންދެއްވައި ވަހީކުރައްވަމެވެ.","",""],["","","","إن إلهكم لواحد","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ އިލާހަކީ އެއްކައުވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","رب السماوات والأرض وما بينهما ورب المشارق","(އެކަލާނގެއީ) އުޑުތަކާއި، ބިމާއި، އެދެމެދުގައިވާ ތަނާއި، ތަރިރުހަނދުއަރާ އުދަރެސްތަކުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["","","","إنا زينا السماء الدنيا بزينة الكواكب","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އަލިގަދަ ތަރިތަކުގެ ޒީނަތްތެރިކަމުން އެންމެކައިރި އުޑު ޒީނަތްތެރި ކުރެއްވީމެވެ.","",""],["","","","وحفظا من كل شيطان مارد","އަދި ނުކިޔަމަންތެރި ކޮންމެ ޝައިތާނެއްގެ ކިބައިން އެ އުޑު ރައްކާތެރިކުރެއްވީމެވެ.","",""],["","","","لا يسمعون إلى الملإ الأعلى ويقذفون من كل جانب","މަތިވެރިވެގެންވާ ޖަމާއަތުން ދައްކަވާ ވާހަކަފުޅަށް (އެބަހީ: މަލާއިކަތުން ދައްކަވާ ވާހަކަފުޅަށް) އަޑުއެހުމަކަށް އެ ޝައިތާނުންނަށް ކުޅަދާނަވެގެންނެއް ނުވެތެވެ. އަދި ހުރިހާ ފަރާތަކުން އެ ޝައިތާނުންނާ ދިމާޔަށް ގިނިހިލަ އުއްކަވާނެތެވެ.","",""],["","","","دحورا ولهم عذاب واصب","ބޭރުކޮށް ފައްސައިލުމުގެ ގޮތުންނެވެ. އަދި ކެނޑިގެންނުދާނެ އަޒާބެއުރެންނަށް ހުށްޓެވެ.","",""],["","","","إلا من خطف الخطفة فأتبعه شهاب ثاقب","ކުއްލިގޮތެއްގައި ސިއްރުން އެހުމެއް އަހައިފި ޝައިތާނަކު މެނުވީއެވެ. ފަހެ، އެ ޝައިތާނާގެ ފަހަތުން ތޮރުފައިލާފަދަ ގިނިހިލައެއް ފޮނުއްވާހުށްޓެވެ.","",""],["","","","فاستفتهم أهم أشد خلقا أم من خلقنا إنا خلقناهم من طين لازب","ފަހެ، ކަލޭގެފާނު އެއުރެންނާ ސުވާލުކުރައްވައިބައްލަވާށެވެ! އުނދަގޫކަންބޮޑީ، އެއުރެން ހެއްދެވުންހޭ؟ ނުވަތަ ތިމަންރަސްކަލާނގެ ހެއްދެވި އެނޫންތަކެތިހޭ؟ ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެން (އެބަހީ: އިންސާނުން) ހެއްދެވީ ތަތްލާ މަށިންނެވެ.","",""],["","","","بل عجبت ويسخرون","އަދި ކިއެއްތަ! (އެއުރެން ދޮގުކުރާ ކަމާމެދު) ކަލޭގެފާނު އަޖާއިބު ވެވަޑައިގެންނެވީމުއެވެ. އަދި އެއުރެން އެކަމަށް ފުރައްސާރަކޮށް އުޅެތެވެ.","",""],["","","","وإذا ذكروا لا يذكرون","އަދި އެއުރެންނަށް ހަނދުމަކޮށްދެއްވައިފިނަމަ، އެއުރެން ހަނދުމައެއް ނުކުރެތެވެ.","",""],["","","","وإذا رأوا آية يستسخرون","އަދި އެއުރެންނަށް މުއުޖިޒާއެއް ފެނިއްޖެނަމަ، އެއުރެން ފުރައްސާރަކޮށް އުޅެތެވެ.","",""],["","","","وقالوا إن هذا إلا سحر مبين","އަދި އެއުރެން ބުނޫއެވެ. މިއީ، ފާޅުވެގެންވާ ޖާދޫއެއްކަމުގައި މެނުވީ ނުވެތެވެ.","",""],["","","","أإذا متنا وكنا ترابا وعظاما أإنا لمبعوثون","ތިމަންމެން މަރުވެ، ވެއްޔަށާއި ކަށިތަކަކަށް ވެއްޖެހިނދު، ހަމަކަށަވަރުން، ތިމަންމެންނަކީ، އަލުން ދިރުމަކަށް ފޮނުއްވާނެ ބަޔަކުހެއްޔެވެ؟","",""],["","","","أوآباؤنا الأولون","އަދި ތިމަންމެންގެ އިސްވެދިޔަ ކާބަފައިންވެސް ހެއްޔެވެ؟","",""],["","","","قل نعم وأنتم داخرون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އާނއެކެވެ! ތިޔަބައިމީހުން ނިކަމެތިވެގެންވާ ޙާލު ގައެވެ.","",""],["","","","فإنما هي زجرة واحدة فإذا هم ينظرون","ފަހެ، އެކަންތައް ވާނެކަން ކަށަވަރީ، ބިރުވެރި އެންމެ އަޑަކުންނެވެ. ފަހެ، އެހާރުން، އެއުރެން (ތެދުވެ) ބަލަން ތިބޭނެތެވެ.","",""],["","","","وقالوا يا ويلنا هذا يوم الدين","އަދި އެއުރެން ބުނާނެތެވެ. އޭ ތިމަންމެންނަށްހުރި ހަލާކެއްގެ ބޮޑުކަމާއެވެ! މިއީ ގިޔާމަތް ދުވަހެވެ.","",""],["","","","هذا يوم الفصل الذي كنتم به تكذبون","މިއީ ތިޔަބައިމީހުން އެދުވަހަކާމެދު ދޮގުކޮށް އުޅުނު ނިޔާކުރެއްވުމުގެ ދުވަހެވެ.","",""],["","","","احشروا الذين ظلموا وأزواجهم وما كانوا يعبدون","(މަލާއިކަތުންނަށް އަންގަވާނެތެވެ.) އަނިޔާވެރިވީ މީހުންނާއި، އެއުރެންގެ (އެފަދަ) އަނބިންނާއި، އަދި ﷲ ފިޔަވައި އެއުރެން އަޅުކަންކޮށްއުޅުނު ތަކެތި އެއްކުރައްވާށެވެ! ފަހެ، އެއުރެންނަށް ނަރަކައިގެ މަގަށް މަގުދައްކަވާށެވެ!","",""],["","","","من دون الله فاهدوهم إلى صراط الجحيم","(މަލާއިކަތުންނަށް އަންގަވާނެތެވެ.) އަނިޔާވެރިވީ މީހުންނާއި، އެއުރެންގެ (އެފަދަ) އަނބިންނާއި، އަދި ﷲ ފިޔަވައި އެއުރެން އަޅުކަންކޮށްއުޅުނު ތަކެތި އެއްކުރައްވާށެވެ! ފަހެ، އެއުރެންނަށް ނަރަކައިގެ މަގަށް މަގުދައްކަވާށެވެ!","",""],["","","","وقفوهم إنهم مسئولون","އަދި އެއުރެން ހުއްޓުވާށެވެ! ހަމަކަށަވަރުން، އެއުރެންނީ ސުވާލުކުރައްވާނޭ ބަޔެކެވެ.","",""],["","","","ما لكم لا تناصرون","(މިއަދު) ތިޔަބައިމީހުން އެކަކު އަނެކަކަށް އެހީނުވަނީ ކީއްވެގެންހެއްޔެވެ؟","",""],["","","","بل هم اليوم مستسلمون","އަދި ކިއެއްތަ! އެއުރެން މިއަދު ތިބީ ކިޔަމަންވެ ބޯލަނބައިގެންނެވެ.","",""],["","","","وأقبل بعضهم على بعض يتساءلون","އަދި އެކަކު އަނެކަކާ ސުވާލުކުރަމުން އެއުރެންގެ އެއްބަޔަކު އަނެއްބަޔަކުގެ ގާތަށް ކުރިމަތިލައި އަންނާނެތެވެ.","",""],["","","","قالوا إنكم كنتم تأتوننا عن اليمين","(މަގުފުރެއްދި މީހުންނަށް) އެއުރެން ބުނާނެތެވެ. ހަމަކަށަވަރުން، ތިމަންމެންގެ ކައިރިޔަށް ތިޔަބައިމީހުން ކަނާތްފަރާތުން އަންނަކަމުގައިވީމުއެވެ.","",""],["","","","قالوا بل لم تكونوا مؤمنين","އެއުރެން ބުނާނެތެވެ. އަދި ކިއެއްތަ! ތިޔަބައިމީހުން މުއުމިނުން ކަމުގައި ނުވަމުއެވެ.","",""],["","","","وما كان لنا عليكم من سلطان بل كنتم قوما طاغين","އަދި ތިޔަބައިމީހުންގެ މައްޗަކަށް ތިމަންމެންނަކަށް ބާރެއް ލިބިގެނެއް ނުވެއެވެ. އަދި ކިއެއްތަ! ތިޔަބައިމީހުންވީ (ފުރެދުމުގައި) ހައްދުފަހަނަޅައިފައިވާ ބަޔަކު ކަމުގައެވެ.","",""],["","","","فحق علينا قول ربنا إنا لذائقون","ފަހެ، ތިމަންމެންގެ މައްޗަށް، ތިމަންމެންގެ ވެރިރަސްކަލާނގެ އަޒާބުގެ ބަސްފުޅު ހައްގު ވެއްޖެއެވެ. ހަމަކަށަވަރުން، ތިމަންމެންނީ އަޒާބުގެ ރަހަ ދެކޭނޭ ބަޔެއްކަން ކަށަވަރެވެ.","",""],["","","","فأغويناكم إنا كنا غاوين","ފަހެ، ތިމަންމެން ތިޔަބައިމީހުން މަގުފުރެއްދީމުއެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންމެންވީ، މަގުފުރެދިގެންވާ ބަޔަކު ކަމުގައެވެ.","",""],["","","","فإنهم يومئذ في العذاب مشتركون","ފަހެ، ހަމަކަށަވަރުން، އެއުރެންނީ އެދުވަހުން އަޒާބުގައި ބައިވެރިވެގެންވާ މީހުންނެވެ.","",""],["","","","إنا كذلك نفعل بالمجرمين","ހަމަކަށަވަރުން، ކުށްވެރިންނާމެދު، ތިމަންރަސްކަލާނގެ ކަންތައްކުރައްވަނީ އެފަދައިންނެވެ.","",""],["","","","إنهم كانوا إذا قيل لهم لا إله إلا الله يستكبرون","ހަމަކަށަވަރުން، ﷲ މެނުވީ އިލާހަކު ނުވާކަމަށް އެއުރެންނަށް ބުނެފިހިނދަކު އެއުރެން ބޮޑާވެގަންނަކަމުގައިވޫއެވެ.","",""],["","","","ويقولون أئنا لتاركو آلهتنا لشاعر مجنون","އަދި އެއުރެން ބުނެތެވެ. ހަމަކަށަވަރުން، މޮޔަވެފައިވާ ޅެންވެރިޔެއްގެ ބަހަށް، ތިމަންމެންގެ އިލާހު ންތައް ތިމަންމެން ދޫކޮށްލާނެ ހެއްޔެވެ؟","",""],["","","","بل جاء بالحق وصدق المرسلين","އަދި ކިއެއްތަ! އެކަލޭގެފާނު ވަޑައިގަތީ، ހައްގު ދީނާއިގެންނެވެ. އަދި އެކަލޭގެފާނު (ކުރީގެ) ރަސޫލުން ތެދުކުރެއްވިއެވެ.","",""],["","","","إنكم لذائقو العذاب الأليم","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނީ، ވޭންދެނިވި އަޒާބުގެ ރަހަ ދެކޭނޭ ބަޔަކުކަން ކަށަވަރެވެ.","",""],["","","","وما تجزون إلا ما كنتم تعملون","އަދި ތިޔަބައިމީހުން ކޮށްއުޅުނު ޢަމަލަކަށްމެނުވީ، ތިޔަބައިމީހުންނަކަށް ޖަޒާއެއް ނުދެއްވާނެތެވެ.","",""],["","","","إلا عباد الله المخلصين","ޚިޔާރުކުރައްވާފައިވާ، ﷲގެ އަޅުން މެނުވީއެވެ.","",""],["","","","أولئك لهم رزق معلوم","އެއުރެންނަށްޓަކައި އެނގިގެންވާ ރިޒްގު ވެއެވެ.","",""],["","","","فواكه وهم مكرمون","(އެއީ) މޭވާތަކެވެ. އަދި އެއުރެންނީ މާތްކުރައްވާފައިވާ ބަޔެކެވެ.","",""],["","","","في جنات النعيم","ނިއުމަތްގެ ސުވަރުގެތަކުގައެވެ.","",""],["","","","على سرر متقابلين","ދާންތަކެއްގެ މަތީގައެވެ. އެކަކު އަނެކަކަށް ކުރިމަތިލައިގެންނެވެ.","",""],["","","","يطاف عليهم بكأس من معين","ހިނގަހިނގާ ހުންނަ އާރަކުން ނެގޭ ބުއިމެއްގެ ތަށިތަކާއިގެން އެއުރެންގެ މެދުގައި ބުރުޖެހޭނެތެވެ.","",""],["","","","بيضاء لذة للشاربين","ބޯމީހުންނަށް މީރު، ހުދުކުލައިގެ ބުއިމެކެވެ.","",""],["","","","لا فيها غول ولا هم عنها ينزفون","އެ ބުއިމުގައި ބޯއެނބުރުމެއްނެތެވެ. އަދި އޭގެސަބަބުން، މަސްތުވެގެންދާނޭ ބަޔަކު ކަމުގައި އެއުރެން ނުވެތެވެ.","",""],["","","","وعندهم قاصرات الطرف عين","އަދި ކަޅިރަވަ ތޫނު، ޢިއްފަތް ތެރި ޙޫރުލްޢީނުން އެއުރެންގެ ގާތުގައިވެއެވެ.","",""],["","","","كأنهن بيض مكنون","ރައްކާތެރި ކުރައްވާފައިވާ (މާދޫނި) ބިސްފަދައިން އެކަނބަލުންވެއެވެ.","",""],["","","","فأقبل بعضهم على بعض يتساءلون","ފަހެ، އެކަކު އަނެކަކާ ސުވާލުކުރަމުން އެއުރެންގެ އެއްބަޔަކު އަނެއްބަޔަކާ ކުރިމަތިލައި އަންނާނެތެވެ.","",""],["","","","قال قائل منهم إني كان لي قرين","އެއުރެންގެ ތެރެއިން ބުނާމީހަކު ބުނާނެތެވެ. ހަމަކަށަވަރުން، ތިމަންނާއަށް އެކުވެރިޔަކު ވިއެވެ.","",""],["","","","يقول أإنك لمن المصدقين","އެ އެކުވެރިޔާ ބުނެއުޅެތެވެ. ހަމަކަށަވަރުން، ތިބާވަނީ ތެދުކުރާ މީހުންގެ ތެރެއިންހެއްޔެވެ؟","",""],["","","","أإذا متنا وكنا ترابا وعظاما أإنا لمدينون","ތިމަންމެން މަރުވެ، ވެއްޔަށާއި ކަށިތަކަކަށްވެއްޖެހިނދު ހަމަކަށަވަރުން، ތިމަންމެންނީ ޖަޒާލިބޭނޭ ބަޔަކުހެއްޔެވެ؟","",""],["","","","قال هل أنتم مطلعون","އޭނާ ބުނާނެތެވެ. ތިޔަބައިމީހުން ބަލަން ބޭނުންހެއްޔެވެ؟","",""],["","","","فاطلع فرآه في سواء الجحيم","ދެން އޭނާ ބަލައިލިއެވެ. ފަހެ، ނަރަކައިގެ މެދުތެރޭގައި އެ އެކުވެރިޔާ ވަނިކޮށް އޭނާޔަށް ފެނުނެވެ.","",""],["","","","قال تالله إن كدت لتردين","އޭނާ ބުނާނެތެވެ. ﷲ ގަންދީ ބުނަމެވެ. ހަމަކަށަވަރުން، ކަލޭ ތިމަން ހަލާކުކޮށްލުމާ ގާތްކުޅައީމުއެވެ.","",""],["","","","ولولا نعمة ربي لكنت من المحضرين","އަދި ތިމަންގެ ވެރިރަސްކަލާނގެ ނިއުމަތް ދެއްވާފައިނުވާނަމަ، (އަޒާބުގެ ތެރެޔަށް) ޙާޒިރުުކުރައްވާފައިވާ މީހުންގެތެރެއިން ތިމަންވެއްޖައީސްކަން ކަށަވަރެވެ.","",""],["","","","أفما نحن بميتين","ފަހެ، ފުރަތަމަ ފަހަރު މަރުވުންމެނުވީ، މަރުނުވެ ދެމިތިބޭނޭ ބަޔަކުކަމުގައި އަހަރެމެން ނުވޭހެއްޔެވެ؟ އަދި އަޒާބު ލިބޭނޭ ބަޔަކުކަމުގައި އަހަރެމެން ނުވަމުއެވެ.","",""],["","","","إلا موتتنا الأولى وما نحن بمعذبين","ފަހެ، ފުރަތަމަ ފަހަރު މަރުވުންމެނުވީ، މަރުނުވެ ދެމިތިބޭނޭ ބަޔަކުކަމުގައި އަހަރެމެން ނުވޭހެއްޔެވެ؟ އަދި އަޒާބު ލިބޭނޭ ބަޔަކުކަމުގައި އަހަރެމެން ނުވަމުއެވެ.","",""],["","","","إن هذا لهو الفوز العظيم","ހަމަކަށަވަރުން، ބޮޑުވެގެންވާ ނަސީބު ލިބުމަކީ މިއީކަން ކަށަވަރެވެ.","",""],["","","","لمثل هذا فليعمل العاملون","ޢަމަލުކުރާ މީހުން މިފަދަކަންތައް ލިބިގަތުމަށްޓަކައި ޢަމަލުކުރާހުށިކަމެވެ!","",""],["","","","أذلك خير نزلا أم شجرة الزقوم","ޟިޔާފަތެއްގެގޮތުން މޮޅީ އެތަންހެއްޔެވެ؟ ނުވަތަ ޒައްގޫމު ގަސް ހެއްޔެވެ؟","",""],["","","","إنا جعلناها فتنة للظالمين","ހަމަކަށަވަރުން، އަނިޔާވެރިންނަށްއޮތް އިމްތިހާނެއްކަމުގައި ތިމަންރަސްކަލާނގެ އެ ގަސް ލެއްވީމެވެ.","",""],["","","","إنها شجرة تخرج في أصل الجحيم","ހަމަކަށަވަރުން، އެއީ ނަރަކައިގެ އަޑިން ފަޅައިގެންހެދޭ ގަހެކެވެ.","",""],["","","","طلعها كأنه رءوس الشياطين","އޭގެ މޭވާ، ޝައިތާނުންގެ ބޯތަކެކޭ އެއްފަދައެވެ.","",""],["","","","فإنهم لآكلون منها فمالئون منها البطون","ފަހެ، ހަމަކަށަވަރުން، އެއުރެންނީ އެއިންކާނޭ ބަޔަކުކަން ކަށަވަރެވެ. އަދި އެއިން ބަނޑުތައް ފުރާނޭ ބަޔެކެވެ.","",""],["","","","ثم إن لهم عليها لشوبا من حميم","ދެން ހަމަކަށަވަރުން، އޭގެމައްޗަށް ކެކިކެކިހުންނަ ހޫނުފެނުގެ ގިރުމެއް (އެބަހީ: ޒައްގޫމާއި ހޫނުފެނާ އެކުވެފައިވާ ދިޔަވަރެއް) އެއުރެންނަށްވާކަން ކަށަވަރެވެ.","",""],["","","","ثم إن مرجعهم لإلى الجحيم","ދެން ހަމަކަށަވަރުން، އެއުރެން އެނބުރި ދިޔުންވަނީ ނަރަކަޔަށްކަން ކަށަވަރެވެ.","",""],["","","","إنهم ألفوا آباءهم ضالين","ހަމަކަށަވަރުން، އެއުރެންގެ ކާބަފައިން މަގުފުރެދިފައިވާތީ، އެއުރެން ދުށްޓެވެ.","",""],["","","","فهم على آثارهم يهرعون","ފަހެ، އެއުރެން އެ ކާބަފައިންގެ ފިޔަވަޅުތަކުގެ މަތީގައި ހިނގައިދިޔުމަށް އަވަސްވެގަނެތެވެ.","",""],["","","","ولقد ضل قبلهم أكثر الأولين","ހަމަކަށަވަރުން، އިސްވެދިޔަމީހުންކުރެ ގިނަމީހުން އޭގެކުރިންވަނީ މަގުފުރެދިފައެވެ.","",""],["","","","ولقد أرسلنا فيهم منذرين","އަދި ހަމަކަށަވަރުން ތިމަންރަސްކަލާނގެ އެއުރެންގެ ތެރެޔަށް އިންޒާރުކުރައްވާ ރަސޫލުން ފޮނުއްވީމެވެ.","",""],["","","","فانظر كيف كان عاقبة المنذرين","ފަހެ، އިންޒާރު ވެވުނު މީހުންގެ ނިމުންއޮތީ ކޮންފަދައަކުންކަން ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާށެވެ!","",""],["","","","إلا عباد الله المخلصين","ﷲގެ، ޚިޔާރުކުރައްވާފައިވާ އަޅުން މެނުވީއެވެ.","",""],["","","","ولقد نادانا نوح فلنعم المجيبون","ހަމަކަށަވަރުން، ނޫޙުގެފާނު ތިމަންރަސްކަލާނގެއަށް (އެހީއަށްއެދި) ގޮވައިލެއްވިއެވެ. ފަހެ (އެކަލޭގެފާނަށް) އިޖާބަދެއްވި ރަސްކަލާނގެ މޮޅުކަމާއެވެ!","",""],["","","","ونجيناه وأهله من الكرب العظيم","އަދި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނާއި، އެކަލޭގެފާނުގެ އަހުލުވެރިން ބޮޑުވެގެންވާ ހިތާމައިން (އެބަހީ: ޣަރަގުން) ސަލާމަތްކުރެއްވީމެވެ.","",""],["","","","وجعلنا ذريته هم الباقين","އަދި ދެންތިބި ބަޔަކީ، އެކަލޭގެފާނުގެ ދަރިކޮޅުކަމުގައި ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ.","",""],["","","","وتركنا عليه في الآخرين","އަދި ފަހުން އަންނަނިވި އުއްމަތްތަކުގެ މެދުގައި އެކަލޭގެފާނަށް ރިވެތި ޘަނާ ލެހެއްޓެވީމެވެ.","",""],["","","","سلام على نوح في العالمين","އާލަމް ތަކުގައި ނޫޙުގެފާނުގެ މައްޗަށް ސަލާމް ހުށްޓެވެ.","",""],["","","","إنا كذلك نجزي المحسنين","އިހްސާން ތެރިންނަށް ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ޖަޒާދެއްވަނީ އެފަދައިންނެވެ.","",""],["","","","إنه من عبادنا المؤمنين","ހަމަކަށަވަރުން، އެކަލޭގެފާނުވަނީ، ތިމަންރަސްކަލާނގެ މުއުމިނު އަޅުންގެ ތެރެއިންނެވެ.","",""],["","","","ثم أغرقنا الآخرين","ދެން ތިމަންރަސްކަލާނގެ އެހެންމީހުން (އެބަހީ: ކާފިރުން) ޣަރަގުކުރެއްވީމެވެ.","",""],["","","","وإن من شيعته لإبراهيم","ހަމަކަށަވަރުން، އެކަލޭގެފާނުންގެ ގޮތަށް ތަބާ ވެގެންވާ މީހުންގެ ތެރެއިން އިބްރާހީމްގެފާނުވެއެވެ.","",""],["","","","إذ جاء ربه بقلب سليم","(އެއީ) ސަލާމަތުންވާ ހިތަކާއިގެން އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ތަވައްޖުހު ވެވަޑައިގެންނެވި ހިނދުގައެވެ.","",""],["","","","إذ قال لأبيه وقومه ماذا تعبدون","(އެއީ) އެކަލޭގެފާނުގެ ބައްޕައަށާއި، އެކަލޭގެފާނުންގެ ގައުމުގެމީހުންނަށް އެކަލޭގެފާނު ވިދާޅުވިހިނދުގައެވެ. ތިޔަބައިމީހުން ތިޔަ އަޅުކަންކުރަނީ ކޮންއެއްޗަކަށް ހެއްޔެވެ؟","",""],["","","","أئفكا آلهة دون الله تريدون","ﷲ ފިޔަވައި ދޮގު އިލާހު ންތަކަކަށް ތިޔަބައިމީހުން އެދެނީ ހެއްޔެވެ؟","",""],["","","","فما ظنكم برب العالمين","ފަހެ، އާލަމްތަކުގެ ވެރިރަސްކަލާނގެއާމެދު، ތިޔަބައިމީހުން ހީކުރަނީ ކީކޭހެއްޔެވެ؟","",""],["","","","فنظر نظرة في النجوم","ފަހެ (އެއުރެންގެ ޢީދަކަށް ނުކުމެވަޑައިގަތުމަށް ދެންނެވުމުން) އެކަލޭގެފާނު ފުން ނަޒަރަކުން ތަރިތަކަށް ބައްލަވައިލެއްވިއެވެ.","",""],["","","","فقال إني سقيم","ދެން ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، އަހުރެންނީ ބަލިމީޙަކީމެވެ.","",""],["","","","فتولوا عنه مدبرين","ދެން އެއުރެން އެކަލޭގެފާނަށް ފުރަގަސްދީ ހިނގައްޖައޫއެވެ.","",""],["","","","فراغ إلى آلهتهم فقال ألا تأكلون","ފަހެ، އެކަލޭގެފާނު އެއުރެންގެ އިލާހު ންތަކުގެ ކައިރިޔަށް ޖެހިވަޑައިގެން ވިދާޅުވިއެވެ. ކަލޭމެން ނުކަނީހެއްޔެވެ؟","",""],["","","","ما لكم لا تنطقون","ކަލޭމެން ބަސްނުމޮށެނީ ކީއްވެގެން ހެއްޔެވެ؟","",""],["","","","فراغ عليهم ضربا باليمين","ފަހެ، އެކަލޭގެފާނު އެތަކެތީގެ ކައިރިޔަށް ޖެހިވަޑައިގެން ކަނާތްޕުޅުން އެތަކެތީގައި ޖެއްސެވިއެވެ.","",""],["","","","فأقبلوا إليه يزفون","ފަހެ، އެއުރެން އެކަލޭގެފާނުގެ އަރިހަށް އަވަސްވެގަނެގެން އައޫއެވެ.","",""],["","","","قال أتعبدون ما تنحتون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން ކޮށައި މަށައިގެންހަދާ ތަކެއްޗަށް ތިޔަބައިމީހުން އަޅުކަންކުރަނީ ހެއްޔެވެ؟","",""],["","","","والله خلقكم وما تعملون","އަދި ތިޔަބައިމީހުންނާއި، ތިޔަބައިމީހުން ކުރާހާކަމެއް ހެއްދެވީ ﷲއެވެ.","",""],["","","","قالوا ابنوا له بنيانا فألقوه في الجحيم","އެއުރެން ބުނޫއެވެ. އެކަލޭގެފާނަށްޓަކައި ބިނާއެއް ހަދާށެވެ! (އަދި އެތަނަށް ދަރުއަޅައި ރޯކޮށްފައި) ދެން ގަދަ އަލިފާންގަނޑުގެ ތެރެޔަށް އެކަލޭގެފާނު އެއްލާށެވެ!","",""],["","","","فأرادوا به كيدا فجعلناهم الأسفلين","ފަހެ، އެއުރެން އެކަލޭގެފާނު ހަލާކުކޮށްލުމަށް މަކަރުވެރި ރޭވުމެއް ރޭވޫއެވެ. އަދި ދެރަވެ ނިކަމެތިވި ބަޔަކު ކަމުގައި ތިމަންރަސްކަލާނގެ އެއުރެން ލެއްވީމެވެ.","",""],["","","","وقال إني ذاهب إلى ربي سيهدين","އަދި އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، އަހުރެން (މިތަނުން ހިޖުރަ ކޮށް) ދާހުށީ އަހުރެންގެ ވެރިރަސްކަލާނގެ އަމުރުކުރެއްވި ތަނަށެވެ. އެކަލާނގެ އަހުރެންނަށް މަގު ދައްކަވާނެތެވެ.","",""],["","","","رب هب لي من الصالحين","އަޅުގެ ވެރިރަސްކަލާކޮ! މިއަޅާއަށް ސާލިހުންގެ ތެރެއިންވާ ދަރިޔަކު ދެއްވާނދޭވެ!","",""],["","","","فبشرناه بغلام حليم","ފަހެ، ތިމަންރަސްކަލާނގެ (އެކަލޭގެފާނުގެ ދުއާ އިޖާބަކުރައްވައި) ޙިލްމުވެރި ދަރިކަލަކު ދެއްވާނެކަމުގެ އުފާވެރި ޚަބަރު އެކަލޭގެފާނަށް ދެއްވީމެވެ.","",""],["","","","فلما بلغ معه السعي قال يا بني إني أرى في المنام أني أذبحك فانظر ماذا ترى قال يا أبت افعل ما تؤمر ستجدني إن شاء الله من الصابرين","ފަހެ، އެކަލޭގެފާނުގެ އަރިހުގައި އެ ދަރިކަލުން މަސައްކަތް ކުރައްވައި އުޅުއްވާ ފުރާވަރަށް އެރިހިނދު، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ ލޯބިވާ ދަރިފުޅާއެވެ! ހަމަކަށަވަރުން، އަހުރެން ތިބާ ގުރުބާންކުރާތީ، ހުވަފެނުގައި އަހުރެންނަށް ފެނެތެވެ. ފަހެ، ތިބާޔަށް (އެކަމާމެދު) ފެންނަގޮތެއް ވިސްނައި ބަލާށެވެ! އެ ދަރިކަލުން ދެންނެވިއެވެ. އޭ ބައްޕާއެވެ! ކަލޭގެފާނަށް އަމުރުކުރައްވާ ކަންތައް ކަލޭގެފާނު ކުރައްވާށެވެ! ﷲ އިރާދަކުރެއްވިއްޔާ އަޅުގަނޑު ވަނީ، ކެތްތެރިންގެ ތެރެއިންކަން، ކަލޭގެފާނަށް ފެނިވަޑައިގަންނަވާނެތެވެ.","",""],["","","","فلما أسلما وتله للجبين","ފަހެ، އެ ދެބަފައިކަލުން (ﷲއަށް) ބޯލަނބައި ކިޔަމަންވެ، އެ ދަރިކަލުން ނިތްކުރިވަތަށް ބޭއްވެވިހިނދު، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ނިދާއިއްވެވީމެވެ. އޭ އިބްރާހީމްގެފާނެވެ!","",""],["","","","وناديناه أن يا إبراهيم","ފަހެ، އެ ދެބަފައިކަލުން (ﷲއަށް) ބޯލަނބައި ކިޔަމަންވެ، އެ ދަރިކަލުން ނިތްކުރިވަތަށް ބޭއްވެވިހިނދު، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ނިދާއިއްވެވީމެވެ. އޭ އިބްރާހީމްގެފާނެވެ!","",""],["","","","قد صدقت الرؤيا إنا كذلك نجزي المحسنين","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ހުވަފެންފުޅު ތެދުކުރައްވައިފީމުއެވެ. އިހްސާން ތެރިންނަށް ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ޖަޒާދެއްވަނީ އެފަދައިންނެވެ.","",""],["","","","إن هذا لهو البلاء المبين","ހަމަކަށަވަރުން، މިއީ ފާޅުވެ ބަޔާންވެގެންވާ އިމްތިހާނު ކަން ކަށަވަރެވެ.","",""],["","","","وفديناه بذبح عظيم","އަދި ގަދަރު ބޮޑުވެގެންވާ (ކަންބަޅި ބަކަރިއެއް) ކަތިލައްވައިގެން ތިމަންރަސްކަލާނގެ، އެކަލޭގެފާނު ސަލާމަތް ކުރެއްވީމެވެ.","",""],["","","","وتركنا عليه في الآخرين","އަދި ފަހުން އަންނަނިވި އުއްމަތްތަކުގެ މެދުގައި އެކަލޭގެފާނަށް ރިވެތި ޘަނާ ލެހެއްޓެވީމެވެ.","",""],["","","","سلام على إبراهيم","އިބްރާހީމްގެފާނުގެ މައްޗަށް ސަލާމް ހުށްޓެވެ.","",""],["","","","كذلك نجزي المحسنين","އިހްސާން ތެރިންނަށް ތިމަންރަސްކަލާނގެ ޖަޒާދެއްވަނީ އެފަދައިންނެވެ.","",""],["","","","إنه من عبادنا المؤمنين","ހަމަކަށަވަރުން، އެކަލޭގެފާނުވަނީ، ތިމަންރަސްކަލާނގެ މުއުމިނު އަޅުންގެ ތެރެއިންނެވެ.","",""],["","","","وبشرناه بإسحاق نبيا من الصالحين","އަދި ސާލިހުންގެ ތެރެއިންވާ ނަބިއްޔަކު ކަމުގައި އިސްޙާގުގެފާނު ދެއްވާނެކަމުގެ އުފާވެރި ޚަބަރު، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ދެއްވީމެވެ.","",""],["","","","وباركنا عليه وعلى إسحاق ومن ذريتهما محسن وظالم لنفسه مبين","އަދި އެކަލޭގެފާނާއި، އިސްޙާގުގެފާނުގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ބަރަކާތް ލެއްވީމެވެ. އެ ދެބަފައިކަލުންގެ ދަރިކޮޅުން ހެޔޮކަންތައްކުރާ މީހުންނާއި، ފާޅުވެގެންވާ ގޮތުގައި އަމިއްލަ ނަފްސަށް އަނިޔާކުރާ މީހުންވެއެވެ.","",""],["","","","ولقد مننا على موسى وهارون","އަދި މޫސާގެފާނާއި، ހާރޫނުގެފާނަށް ތިމަންރަސްކަލާނގެ (ނަބީކަމުގެ) ނިއުމަތް ދެއްވީމެވެ.","",""],["","","","ونجيناهما وقومهما من الكرب العظيم","އަދި ތިމަންރަސްކަލާނގެ އެ ދެބޭކަލުންނާއި، އެ ދެބޭކަލުންގެ ގައުމުގެމީހުން ބޮޑުވެގެންވާ ހިތާމައިން ސަލާމަތް ކުރެއްވީމެވެ.","",""],["","","","ونصرناهم فكانوا هم الغالبين","އަދި ތިމަން ރަސްކަލާނގެ އެއުރެންނަށް ނަސްރު ދެއްވީމެވެ. ފަހެ، ގަދަވިބަޔަކު ކަމުގައިވީ، ހަމައެއުރެންނެވެ.","",""],["","","","وآتيناهما الكتاب المستبين","އަދި ތިމަންރަސްކަލާނގެ އެ ދެބޭކަލުންނަށް ބަޔާން ވެގެންވާ ފޮތް (އެބަހީ: ތައުރާތު) ދެއްވީމެވެ.","",""],["","","","وهديناهما الصراط المستقيم","އަދި ތިމަންރަސްކަލާނގެ، އެ ދެބޭކަލުންނަށް ސީދާވެގެންވާ ތެދުމަގަށް މަގުދެއްކެވީމެވެ.","",""],["","","","وتركنا عليهما في الآخرين","އަދި ފަހުން އަންނަވި އުއްމަތްތަކުގެ މެދުގައި އެ ދެބޭކަލުންނަށް ރިވެތި ޘަނާ ލެހެއްޓެވީމެވެ.","",""],["","","","سلام على موسى وهارون","މޫސާގެފާނާއި، ހާރޫނުގެފާނުގެ މައްޗަށް ސަލާމް ހުށްޓެވެ.","",""],["","","","إنا كذلك نجزي المحسنين","އިހްސާން ތެރިންނަށް، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ޖަޒާދެއްވަނީ އެފަދައިންނެވެ.","",""],["","","","إنهما من عبادنا المؤمنين","ހަމަކަށަވަރުން، އެ ދެބޭކަލުންވަނީ ތިމަންރަސްކަލާނގެ، މުއުމިނު އަޅުންގެ ތެރެއިންނެވެ.","",""],["","","","وإن إلياس لمن المرسلين","ހަމަކަށަވަރުން، އިލްޔާސްގެފާނުވަނީ ރަސޫލުންގެ ތެރެއިންކަން ކަށަވަރެވެ.","",""],["","","","إذ قال لقومه ألا تتقون","އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް އެކަލޭގެފާނު ވިދާޅުވިހިނދުގައެވެ. ތިޔަބައިމީހުން ތަގުވާވެރި ނުވާނޫހެއްޔެވެ؟","",""],["","","","أتدعون بعلا وتذرون أحسن الخالقين","އެންމެ ފުރިހަމަޔަށް ތަކެތި ހައްދަވާ ރަސްކަލާނގެއަށް އަޅުކަންކުރުން ދޫކޮށް، ތިޔަބައިމީހުން ބަޢުލަށް އަޅުކަންކުރަނީ ހެއްޔެވެ؟ (ބަޢުލަކީ އެއުރެން އަޅުކަން ކުރުމަށް ހަދާފައިވާ ބުދެކެވެ.)","",""],["","","","الله ربكم ورب آبائكم الأولين","އެކަލާނގެއީ، ތިޔަބައިމީހުންގެ ވެރި، އަދި ތިޔަބައިމީހުންގެ އިސްވެދިޔަ ކާބަފައިންގެ ވެރި ﷲއެވެ.","",""],["","","","فكذبوه فإنهم لمحضرون","ފަހެ، އެއުރެން އެކަލޭގެފާނު ދޮގުކުރޫއެވެ. ފަހެ، ހަމަކަށަވަރުން، އެއުރެން (އަޒާބުގެ ތެރެޔަށް) ޙާޒިރުުކުރައްވާނެކަން ކަށަވަރެވެ.","",""],["","","","إلا عباد الله المخلصين","ﷲގެ، ޚިޔާރުކުރައްވާފައިވާ އަޅުން މެނުވީއެވެ.","",""],["","","","وتركنا عليه في الآخرين","އަދި ފަހުން އަންނަނިވި އުއްމަތްތަކުގެ މެދުގައި އެކަލޭގެފާނަށް ރިވެތި ޘަނާ ލެހެއްޓެވީމެވެ.","",""],["","","","سلام على إل ياسين","އިލްޔާސްގެފާނުގެ މައްޗަށް ސަލާމް ހުށްޓެވެ.","",""],["","","","إنا كذلك نجزي المحسنين","އިހްސާން ތެރިންނަށް ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ޖަޒާދެއްވަނީ އެފަދައިންނެވެ.","",""],["","","","إنه من عبادنا المؤمنين","ހަމަކަށަވަރުން، އެކަލޭގެފާނު ވަނީ، ތިމަންރަސްކަލާނގެ، މުއުމިނު އަޅުންގެ ތެރެއިންނެވެ.","",""],["","","","وإن لوطا لمن المرسلين","ހަމަކަށަވަރުން، ލޫޠުގެފާނުވަނީ ރަސޫލުންގެ ތެރެއިންކަން ކަށަވަރެވެ.","",""],["","","","إذ نجيناه وأهله أجمعين","ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނާއި، އެކަލޭގެފާނުގެ އަހުލުވެރި އެންމެން ސަލާމަތްކުރެއްވިހިނދު ހަނދުމަކުރާށެވެ!","",""],["","","","إلا عجوزا في الغابرين","އަޒާބު ލިބުނު މީހުންގެ ތެރޭގައިވި، މުސްކުޅި އަންހެނަކު މެނުވީއެވެ.","",""],["","","","ثم دمرنا الآخرين","ދެން ތިމަންރަސްކަލާނގެ (އެ ގައުމުގެ) އެހެންމީހުން ހަލާކު ކުރެއްވީމެވެ.","",""],["","","","وإنكم لتمرون عليهم مصبحين","ހަމަކަށަވަރުން (ތިޔަބައިމީހުންގެ ދަތުރުތަކުގައި) އެއުރެންގެ (އާޘާރުތަކުގެ) ކައިރިންލާފައި ހެނދުނާއި، ރޭގަނޑުގައި ތިޔަބައިމީހުން ދަމުއެވެ. ފަހެ، ތިޔަބައިމީހުން ނުވިސްނަނީ ހެއްޔެވެ؟","",""],["","","","وبالليل أفلا تعقلون","ހަމަކަށަވަރުން (ތިޔަބައިމީހުންގެ ދަތުރުތަކުގައި) އެއުރެންގެ (އާޘާރުތަކުގެ) ކައިރިންލާފައި ހެނދުނާއި، ރޭގަނޑުގައި ތިޔަބައިމީހުން ދަމުއެވެ. ފަހެ، ތިޔަބައިމީހުން ނުވިސްނަނީ ހެއްޔެވެ؟","",""],["","","","وإن يونس لمن المرسلين","ހަމަކަށަވަރުން، ޔޫނުސްގެފާނުވަނީ، ރަސޫލުންގެ ތެރެއިންކަން ކަށަވަރެވެ.","",""],["","","","إذ أبق إلى الفلك المشحون","އެކަލޭގެފާނު ފިއްލަވައިގެން ވަޑައިގެން، ބަރާވެގެންވާ ނަވަށް އަރާވަޑައިގެންނެވިހިނދު ހަނދުމަކުރާށެވެ!","",""],["","","","فساهم فكان من المدحضين","ފަހެ، އެކަލޭގެފާނު (ނަވުގެ މީހުންނާއެކު) ގުރުޢަތު ލެއްވިއެވެ. ފަހެ، އެކަލޭގެފާނުވީ (ގުރުޢަތުން) ދެރަވިމީހުންގެ ތެރެއިންނެވެ.","",""],["","","","فالتقمه الحوت وهو مليم","ފަހެ، އެހިނދު މަހެއް (އައިސް) އެކަލޭގެފާނު (އޮތްގޮތަށް) ދިރުވައިލިއެވެ. (އެއީ) އެކަލޭގެފާނަށް މަލާމާތް ލިބިވަޑައިގެންވާ ޙާލު ގައެވެ.","",""],["","","","فلولا أنه كان من المسبحين","ފަހެ، އެކަލޭގެފާނު ގިނަގިނައިން ތަސްބީހަ ކިޔާ މީހުންގެ ތެރެއިން ނުވިނަމަ، އެއުރެން މަހުޝަރަށް ފޮނުއްވާ ދުވަހަށް ދާނދެން އެ މަހުގެ ބަނޑުތެރޭގައި އެކަލޭގެފާނު ވެއްޖައީހެވެ.","",""],["","","","للبث في بطنه إلى يوم يبعثون","ފަހެ، އެކަލޭގެފާނު ގިނަގިނައިން ތަސްބީހަ ކިޔާ މީހުންގެ ތެރެއިން ނުވިނަމަ، އެއުރެން މަހުޝަރަށް ފޮނުއްވާ ދުވަހަށް ދާނދެން އެ މަހުގެ ބަނޑުތެރޭގައި އެކަލޭގެފާނު ވެއްޖައީހެވެ.","",""],["","","","فنبذناه بالعراء وهو سقيم","ފަހެ، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނު ބަލިޙާލު ކޮޅުގައި ވަނިކޮށް (މަހުގެ ބަނޑުން) އައްސޭރިއަށް އެކަލޭގެފާނު އެއްލެވީމެވެ.","",""],["","","","وأنبتنا عليه شجرة من يقطين","އަދި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށްޓަކައި، ބަރަބޯ ގަހެއް އެތަނުން ފެޅުއްވީމެވެ.","",""],["","","","وأرسلناه إلى مائة ألف أو يزيدون","އަދި ސަތޭކަހާސް މީހުން، ނުވަތަ އެއަށްވުރެ ގިނަމީހުންގެ ގައުމަކަށް ރަސޫލުކަމާއިގެން ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނު ފޮނުއްވީމެވެ.","",""],["","","","فآمنوا فمتعناهم إلى حين","ފަހެ، އެއުރެން (އެކަލޭގެފާނަށް) އީމާން ވޫއެވެ. ދެން އެއުރެންގެ އަޖަލު ޖެހިއްޖައުމަށް ދާނދެން އެއުރެން އަރާމުގައި އުޅުމަށް ލެހެއްޓެވީމެވެ.","",""],["","","","فاستفتهم ألربك البنات ولهم البنون","(އޭ މުޙައްމަދުގެފާނެވެ!) ފަހެ، ކަލޭގެފާނު އެއުރެންނާ ސުވާލުކުރައްވައި ބައްލަވާށެވެ! ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް އަންހެންދަރިން ތިބެފައި އެއުރެންނަށް ފިރިހެންދަރިން ވަނީހެއްޔެވެ؟","",""],["","","","أم خلقنا الملائكة إناثا وهم شاهدون","ނުވަތަ އެއުރެން ޙާޒިރުުވެ ބަލަންތިއްބައި، ތިމަންރަސްކަލާނގެ މަލާއިކަތުން އަންހެންބަޔަކަށް ހެއްދެވީހެއްޔެވެ؟","",""],["","","","ألا إنهم من إفكهم ليقولون","ދަންނާށެވެ! ހަމަކަށަވަރުން، ﷲއަށް ދަރިންވާކަމަށް އެއުރެން އެބުނަނީ ބޮޑުދޮގެއް ހެދުމުގެ ގޮތުންނެވެ. ހަމަކަށަވަރުން، އެއުރެންނީ ދޮގުވެރިންކަން ކަށަވަރެވެ.","",""],["","","","ولد الله وإنهم لكاذبون","ދަންނާށެވެ! ހަމަކަށަވަރުން، ﷲއަށް ދަރިންވާކަމަށް އެއުރެން އެބުނަނީ ބޮޑުދޮގެއް ހެދުމުގެ ގޮތުންނެވެ. ހަމަކަށަވަރުން، އެއުރެންނީ ދޮގުވެރިންކަން ކަށަވަރެވެ.","",""],["","","","أصطفى البنات على البنين","ފިރިހެންދަރިންގެ މައްޗަށް އަންހެންދަރިން އެކަލާނގެ ޚިޔާރުކުރެއްވީހެއްޔެވެ؟","",""],["","","","ما لكم كيف تحكمون","ތިޔަބައިމީހުން ތިޔަތިބީ ކީއްވެފައި ހެއްޔެވެ؟ ތިޔަބައިމީހުން ތިޔަ ހުކުމްކުރަނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","أفلا تذكرون","ފަހެ، ތިޔަބައިމީހުން ހަނދުމަނުކުރަނީ ހެއްޔެވެ؟","",""],["","","","أم لكم سلطان مبين","ނުވަތަ ތިޔަބައިމީހުންނަށް ބަޔާން ވެގެންވާ ދަލީލެއް ވަނީހެއްޔެވެ؟","",""],["","","","فأتوا بكتابكم إن كنتم صادقين","ފަހެ، ތިޔަބައިމީހުން ތެދުވެރިން ކަމުގައިވަނީނަމަ، ތިޔަބައިމީހުންގެ ފޮތް (ދަލީލަކަށް) ގެނެސްބަލާށެވެ!","",""],["","","","وجعلوا بينه وبين الجنة نسبا ولقد علمت الجنة إنهم لمحضرون","އަދި އެއުރެން އެކަލާނގެއާ ޖިންނީންނާ ދެމެދު ނަސަބުގެ ގުޅުމެއް ވާކަމަށް ހަދަތެވެ. ހަމަކަށަވަރުން، އެއުރެން (އަޒާބުގެ ތެރެޔަށް) ޙާޒިރުުކުރައްވާނެކަން، ޖިންނީން ރަނގަޅަށް ދަނެތެވެ.","",""],["","","","سبحان الله عما يصفون","އެއުރެން އެ ސިފަކުރާ ގޮތްތަކުން ﷲ ހުސްތާހިރުވެ ވޮޑިގެންވެއެވެ.","",""],["","","","إلا عباد الله المخلصين","ﷲގެ، ޚިޔާރުކުރައްވާފައިވާ އަޅުން މެނުވީއެވެ.","",""],["","","","فإنكم وما تعبدون","ފަހެ، ތިޔަބައިމީހުންވަނީ، ތިޔަބައިމީހުން އަޅުކަންކުރާ ތަކެއްޗާ އެކުގައެވެ.","",""],["","","","ما أنتم عليه بفاتنين","ނަރަކަޔަށް ވަންނަހުށި މީހަކު މެނުވީ، ތިޔަބައިމީހުންނަކަށް މަގުފުރައްދައެއް ނުލެވޭނެތެވެ.","",""],["","","","إلا من هو صال الجحيم","ނަރަކަޔަށް ވަންނަހުށި މީހަކު މެނުވީ، ތިޔަބައިމީހުންނަކަށް މަގުފުރައްދައެއް ނުލެވޭނެތެވެ.","",""],["","","","وما منا إلا له مقام معلوم","(މަލާއިކަތުން ވިދާޅުވޫއެވެ.) ތިމަންބޭކަލުންގެ ތެރެއިން ހަމައެކަކަށްވެސް (އަޅުކަން ކުރުމަށް) އެބޭކަލަކަށް ކަނޑައެޅިގެންވާ މަގާމެއް ނެތިއެއް ނުވެއެވެ.","",""],["","","","وإنا لنحن الصافون","އަދި ހަމަކަށަވަރުން، ތިމަންމެންނީ ސަފުސަފަށް އެތުރޭ މަލާއިކަތުންނީމުއެވެ.","",""],["","","","وإنا لنحن المسبحون","އަދި ހަމަކަށަވަރުން، ތިމަންމެންނީ ތަސްބީހަ ކިޔާ މަލާއިކަތުންނީމުއެވެ.","",""],["","","","وإن كانوا ليقولون","އަދި ހަމަކަށަވަރުން، އެއުރެން (އެބަހީ: މައްކާގެ މުޝްރިކުން) ބުނެއުޅެތެވެ.","",""],["","","","لو أن عندنا ذكرا من الأولين","ތިމަންމެންގެ ގާތުގައި، އިހުގެ އުއްމަތްތަކަށް ބާވައިލެއްވި ފޮތްތަކުގެ ތެރެއިން ފޮތެއްވާނަމަ، ﷲގެ، ޚިޔާރުކުރައްވާފައިވާ އަޅުންކަމުގައި ތިމަންމެންވެސް ވީމުހެވެ.","",""],["","","","لكنا عباد الله المخلصين","ތިމަންމެންގެ ގާތުގައި، އިހުގެ އުއްމަތްތަކަށް ބާވައިލެއްވި ފޮތްތަކުގެ ތެރެއިން ފޮތެއްވާނަމަ، ﷲގެ، ޚިޔާރުކުރައްވާފައިވާ އަޅުންކަމުގައި ތިމަންމެންވެސް ވީމުހެވެ.","",""],["","","","فكفروا به فسوف يعلمون","ފަހެ (އެ ގުރްއާނެއުރެންގެ ގާތަށް އައުމުން) އެއުރެން އެއަށް ކާފިރު ވޫއެވެ. ފަހެ، އެއުރެންނަށް (އެކަމުގެ ނަތީޖާ) ނިކަންހުރެ އެނގޭހުށްޓެވެ.","",""],["","","","ولقد سبقت كلمتنا لعبادنا المرسلين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އަޅުންކަމުގައިވާ ރަސޫލުންނަށް ތިމަންރަސްކަލާނގެ (ނަސްރު ދެއްވާނެކަމުގެ) ބަސްފުޅުވަނީ، އިސްވެގޮސްފައެވެ.","",""],["","","","إنهم لهم المنصورون","ހަމަކަށަވަރުން، އެބޭކަލުންނީ، ހަމަ ނަސްރު ލިބިގެންވާ ބޭކަލުންނެވެ.","",""],["","","","وإن جندنا لهم الغالبون","އަދި ހަމަކަށަވަރުން، ގަދަވާނެ ބަޔަކީ ހަމަ ތިމަންރަސްކަލާނގެ ލަޝްކަރު ކަން ކަށަވަރެވެ.","",""],["","","","فتول عنهم حتى حين","ފަހެ، ކަނޑައެޅިގެންވާ މުއްދަތަކަށް ކަލޭގެފާނު އެއުރެންނާ އެއްކިބާވެވަޑައިގަންނަވާށެވެ!","",""],["","","","وأبصرهم فسوف يبصرون","އަދި ކަލޭގެފާނު އެއުރެން (ނަށްވާގޮތް) ދެކެވަޑައިގަންނަވާށެވެ! ފަހެ، ނިކަންހުރެ އެއުރެން ދެކޭނެމެއެވެ.","",""],["","","","أفبعذابنا يستعجلون","ފަހެ، އެއުރެން އަވަސްވުން އެދެނީ، ތިމަންރަސްކަލާނގެ އަޒާބަށް ހެއްޔެވެ؟","",""],["","","","فإذا نزل بساحتهم فساء صباح المنذرين","ފަހެ، އެއުރެން ތިބޭތަނަށް އެ އަޒާބު އަތުވެއްޖެނަމަ، އެ އިންޒާރު ވެވުނު މީހުންގެ ހެނދުނުގެ ހުރި ނުބައިކަމާއެވެ!","",""],["","","","وتول عنهم حتى حين","އަދި ކަނޑައެޅިގެންވާ މުއްދަތަކަށް ކަލޭގެފާނު އެއުރެންނާ އެއްކިބާވެ ވަޑައިގަންނަވާށެވެ!","",""],["","","","وأبصر فسوف يبصرون","އަދި ކަލޭގެފާނު (އެއުރެންނަށްވާގޮތް) ދެކެވަޑައިގަންނަވާށެވެ! ފަހެ، ނިކަންހުރެ އެއުރެން ދެކޭނޭމެއެވެ.","",""],["","","","سبحان ربك رب العزة عما يصفون","އެއުރެން ސިފަކުރާ ކަންތަކުން ކަލޭގެފާނުގެ ވެރި، ޢިއްޒަތްގެ ވެރިރަސްކަލާނގެ ހުސްތާހިރުވެ ވޮޑިގެންވެއެވެ.","",""],["","","","وسلام على المرسلين","އަދި (އެންމެހާ) ރަސޫލުންގެ މައްޗަށް ސަލާމް ހުށްޓެވެ.","",""],["","","","والحمد لله رب العالمين","އަދި ހަމްދު ހުރީ، އާލަމްތަކުގެ ވެރި ﷲއަށެވެ.","",""],["","","","بسم الله الرحمن الرحيم ص والقرآن ذي الذكر","ص (މިއަކުރުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.) ހަނދާންކޮށްދިނުމުގެ ވެރި ގުރްއާން ގަންދެއްވައި ވަހީކުރައްވަމެވެ. (ހަމަކަށަވަރުން، އެއީ ހައްގު ތެދެވެ.)","",""],["","","","بل الذين كفروا في عزة وشقاق","އަދި ކިއެއްތަ! ކާފިރުވި މީހުންވަނީ ބޮޑާކަމާއި، ދެކޮޅުވެރިކަމެއްގައެވެ.","",""],["","","","كم أهلكنا من قبلهم من قرن فنادوا ولات حين مناص","އެއުރެންގެކުރިން ތިމަންރަސްކަލާނގެ ކިތައްކިތައް އުއްމަތް ހަލާކުކުރެއްވިން ހެއްޔެވެ؟ ފަހެ (އެއުރެންނަށް އަޒާބު އައިހިނދު) އެހީއަށްއެދި އެއުރެން ގޮވޫއެވެ. (އެހެނެއްކަމަކު) އެ ވަގުތަކީ، ސަލާމަތްވާންދާނެ ތަނެއްއޮތް ވަގުތެއްނޫނެވެ.","",""],["","","","وعجبوا أن جاءهم منذر منهم وقال الكافرون هذا ساحر كذاب","އަދި އެއުރެންގެ ތެރެއިން އިންޒާރުކުރައްވާ ބޭކަލަކު، އެއުރެންގެ ގާތަށް ވަޑައިގަތުމުން، އެކަމާ އެއުރެން އަޖާއިބު ވޫއެވެ. އަދި އެ ކާފިރު ވިމީހުން ބުނޫއެވެ. މިއީ ބޮޑު ދޮގުވެރި ޖާދޫގަރެކެވެ.","",""],["","","","أجعل الآلهة إلها واحدا إن هذا لشيء عجاب","އެކަލޭގެފާނު ހުރިހާ އިލާހުން އެއް އިލާހަކަށް ހެއްދެވީހެއްޔެވެ؟ ހަމަކަށަވަރުން، މިއީ ނުހަނު އަޖާއިބު ވާފަދަ ކަމެއްކަން ކަށަވަރެވެ.","",""],["","","","وانطلق الملأ منهم أن امشوا واصبروا على آلهتكم إن هذا لشيء يراد","އަދި އެއުރެންގެ (އެބަހީ: މައްކާގެ ކާފިރުންގެ) ބޮޑުން (އެ މަޖްލިސްން ވަކިވެ) ހިނގައިގެންފައި ބުނޫއެވެ. ހިނގާށެވެ! އަދި ތިޔަބައިމީހުންގެ އިލާހުންނަށް އަޅުކަން ކުރުންމަތީ ކެތްކޮށްގެން ތިބޭށެވެ! ހަމަކަށަވަރުން، މިއީ (ތިމަންމެންނާމެދު) ރޭވި ގަސްދުކުރެވޭ ކަމެއްކަން ކަށަވަރެވެ.","",""],["","","","ما سمعنا بهذا في الملة الآخرة إن هذا إلا اختلاق","އެންމެފަހު މިއްލަތު ގައިވެސް (އެބަހީ: ޢީސާގެފާނުގެ މިއްލަތު ގައިވެސް) މިކަހަލަ ވާހަކައެއް ތިމަންމެން ނާހަމުއެވެ. މިއީ ހަދައިގެންއުޅޭ ދޮގެއް ކަމުގައިނޫނީ ނުވެތެވެ.","",""],["","","","أأنزل عليه الذكر من بيننا بل هم في شك من ذكري بل لما يذوقوا عذاب","ގުރްއާން ބާވައިލެއްވީ އަހުރެމެންގެ ތެރެއިން އެކަލޭގެފާނުގެ މައްޗަށްހެއްޔެވެ؟ އަދި ކިއެއްތަ! އެއުރެންވަނީ، ތިމަންރަސްކަލާނގެ ގުރްއާނާމެދު ޝައްކެއްގައެވެ. އަދި ކިއެއްތަ! އެއުރެންނަށް، ތިމަންރަސްކަލާނގެ އަޒާބުގެ ރަހަ އަދި ނުލިބެނީއެވެ.","",""],["","","","أم عندهم خزائن رحمة ربك العزيز الوهاب","ނުވަތަ ކަލޭގެފާނުގެވެރި، ގަދަފަދަވަންތަ، ގިނަގުނަ ނިއުމަތްތައް ދެއްވާ ރަސްކަލާނގެ ރަހުމަތްގެ ޚަޒާނާތައް ވަނީ، އެއުރެންގެ ގާތުގައި ހެއްޔެވެ؟","",""],["","","","أم لهم ملك السماوات والأرض وما بينهما فليرتقوا في الأسباب","ނުވަތަ އުޑުތަކާއި، ބިމާއި، އެދެމެދުގައި ވާހާތަކެތީގެ މަލަކަވެރިކަންވަނީ، އެއުރެންނަށް ހެއްޔެވެ؟ އެހެންވިއްޔާ ހަރުގަނޑަކުން އުޑަށް އަރައިބަލާށެވެ!","",""],["","","","جند ما هنالك مهزوم من الأحزاب","އެއުރެންނީ އެތާނގައި (އެބަހީ: ބަދުރުގައި) ބަލިވާނެ ޖަމާއަތްގެ ތެރެއިން ހިމެނޭ (ނިކަމެތި) ލަޝްކަރެކެވެ.","",""],["","","","كذبت قبلهم قوم نوح وعاد وفرعون ذو الأوتاد","އެއުރެންގެކުރިން ނޫޙުގެފާނުގެ ގައުމުގެމީހުންނާއި، ޢާދު ބާގައިމީހުންނާއި، ކަޑަތަކުގެވެރި ފިރްޢައުނާއި، ޘަމޫދު ބާގައިމީހުންނާއި، ލޫޠުގެފާނުގެ ގައުމުގެމީހުންނާއި، އަލްއައިކަތުގެ އެކުވެރިން ރަސޫލުން ދޮގުކުރޫއެވެ. އެ ޖަމާއަތް ތަކަކީ އެއީއެވެ.","",""],["","","","وثمود وقوم لوط وأصحاب الأيكة أولئك الأحزاب","އެއުރެންގެކުރިން ނޫޙުގެފާނުގެ ގައުމުގެމީހުންނާއި، ޢާދު ބާގައިމީހުންނާއި، ކަޑަތަކުގެވެރި ފިރްޢައުނާއި، ޘަމޫދު ބާގައިމީހުންނާއި، ލޫޠުގެފާނުގެ ގައުމުގެމީހުންނާއި، އަލްއައިކަތުގެ އެކުވެރިން ރަސޫލުން ދޮގުކުރޫއެވެ. އެ ޖަމާއަތް ތަކަކީ އެއީއެވެ.","",""],["","","","إن كل إلا كذب الرسل فحق عقاب","އެއިން ކޮންމެބަޔަކުމެ، ރަސޫލުން ދޮގުކުރިބަޔަކު ކަމުގައި މެނުވީ ނުވެތެވެ. ފަހެ (އެއުރެންނަށް) ތިމަންރަސްކަލާނގެ އަޒާބު ހައްގު ވެއްޖެއެވެ.","",""],["","","","وما ينظر هؤلاء إلا صيحة واحدة ما لها من فواق","އަދި އެއުރެން ބިރުވެރި އެންމެ އަޑަކަށްމެނުވީ އިންތިޒާރެއް ނުކުރެތެވެ. އެ އަޑު ތަކުރާރުވުމެއްނެތެވެ.","",""],["","","","وقالوا ربنا عجل لنا قطنا قبل يوم الحساب","އެއުރެން ބުނާނެތެވެ. އަޅަމެންގެވެރިރަސްކަލާކޮ! ހިސާބު ބައްލަވާދުވަހުގެ ކުރިން، އަޅަމެންގެ ޢަމަލުތަކުގެ ފަތް، އަޅަމެންނަށް އަވަހަށް ދެއްވާނދޭވެ!","",""],["","","","اصبر على ما يقولون واذكر عبدنا داوود ذا الأيد إنه أواب","އެއުރެން އެބުނާ ބަސްތަކަށް ކަލޭގެފާނު ކެތްކުރައްވާށެވެ! އަދި ތިމަންރަސްކަލާނގެ އަޅު، ދާވޫދުގެފާނު ހަނދުމަކުރައްވާށެވެ! އެކަލޭގެފާނީ، ބާރުގަދަ ބޭކަލެކެވެ. ހަމަކަށަވަރުން، އެކަލޭގެފާނީ ގިނަގިނައިން ތައުބާ ވެވަޑައިގަންނަވާ ބޭކަލެކެވެ.","",""],["","","","إنا سخرنا الجبال معه يسبحن بالعشي والإشراق","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ފަރުބަދަތައް ޚިދުމަތް ތެރި ކުރެއްވީމެވެ. އެތަކެތި، އެކަލޭގެފާނުގެ އަރިހުގައި ހަވީރާއި، ހެނދުނުގައި ތަސްބީހަ ދަންނަވަތެވެ.","",""],["","","","والطير محشورة كل له أواب","އަދި ދޫނިސޫފާސޫފި ޖަމާކުރައްވާފައިވާ ޙާލު، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ޚިދުމަތް ތެރި ކުރެއްވީމެވެ. އެހުރިހާ ތަކެތިވަނީ، އެކަލޭގެފާނަށް ތަބާވެ، ކިޔަމަންވެގެންނެވެ.","",""],["","","","وشددنا ملكه وآتيناه الحكمة وفصل الخطاب","އަދި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނުގެ ރަސްކަން ގަދަފަދަކޮށްދެއްވީމެވެ. އަދި ނަބީކަމާއި، އޮޅުމެއްނެތް ބަޔާންވެގެންވާ ވާހަކަފުޅުދެއްކެވުން ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ދެއްވީމެވެ.","",""],["","","","وهل أتاك نبأ الخصم إذ تسوروا المحراب","(ދާވޫދުގެފާނު އަޅުކަން ކުރައްވަން އިންނަވާ) މިޙުރާބުގެ ފާރުމަތިންއެރި ޚަޞްމުންގެ ޚަބަރު، ކަލޭގެފާނާ ހަމަޔަށް އައިސްފައިވޭތޯއެވެ؟","",""],["","","","إذ دخلوا على داوود ففزع منهم قالوا لا تخف خصمان بغى بعضنا على بعض فاحكم بيننا بالحق ولا تشطط واهدنا إلى سواء الصراط","އެއުރެން، ދާވޫދުގެފާނު އިންނެވިތަނަށް ވަންހިނދު، އެކަލޭގެފާނު އެއުރެންދެކެ ސިހިވަޑައިގެންނެވިއެވެ. އެއުރެން ދެންނެވޫއެވެ. ބިރުފުޅުގެން ވަޑައިނުގަންނަވާށެވެ! ތިމަންމެންނީ ދެ ޚަޞްމުންނެވެ. ތިމަންމެންގެ އެކަކު އަނެކަކަށް އަނިޔާކޮށްފިއެވެ. ފަހެ، ކަލޭގެފާނު ހައްގު ގޮތުގައި ތިމަންމެންގެ މެދުގައި ހުކުމް ކޮށްދެއްވާށެވެ! އަދި ކަލޭގެފާނު ޢަދުލުން އެއްކިބާވެވަޑައިނުގަންނަވާށެވެ! އަދި ތިމަންމެންނަށް ސީދާވެގެންވާ ތެދުމަގަށް މަގު ދައްކަވާށެވެ!","",""],["","","","إن هذا أخي له تسع وتسعون نعجة ولي نعجة واحدة فقال أكفلنيها وعزني في الخطاب","ހަމަކަށަވަރުން، މިއީ އަޅުގަނޑުގެ އަޚެކެވެ. އޭނާއަށް ނުވަދިހަނުވަ ބަކަރިވެއެވެ. އަދި އަޅުގަނޑަށްވަނީ އެންމެ ބަކަރިއެކެވެ. ފަހެ، އޭނާ ބުންޏެވެ. (އެ ބަކަރިވެސް ތިމަންނާއަށް ދީ) އެ ބަލަހައްޓާ މީހަކީ ތިމަންނާކަމުގައި ހަދާށެވެ! އަދި ވާހަކަ ދައްކައިގެން އޭނާ އަޅުގަނޑުގެ މައްޗަށް ގަދަވެއްޖެއެވެ.","",""],["","","","قال لقد ظلمك بسؤال نعجتك إلى نعاجه وإن كثيرا من الخلطاء ليبغي بعضهم على بعض إلا الذين آمنوا وعملوا الصالحات وقليل ما هم وظن داوود أنما فتناه فاستغفر ربه وخر راكعا وأناب","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިބާގެ ބަކަރި، އޭނާގެ ބަކަރިތަކުގެ ތެރެއަށް އިތުރުކުރުމަށް އެދުމުން، އޭނާ ތިބާޔަށް އަނިޔާކޮށްފިކަން ކަށަވަރެވެ. (މުދާ އެއްކޮށްލައިގެންއުޅޭ) ބައިވެރިންގެ ގިނަމީހުން، ހަމަކަށަވަރުން، އެއްބަޔަކު އަނެއްބަޔަކަށް އަނިޔާކުރެތެވެ. އީމާންވެ، ސާލިހު ޢަމަލުތައްކުޅަ މީހުން މެނުވީއެވެ. އެއުރެންނީ ވަރަށްމަދު ބަޔެކެވެ. އަދި ދާވޫދުގެފާނަށް ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނު އިމްތިހާނުކުރެއްވީކަން އެނގިވަޑައިގެންފިއެވެ. ފަހެ، އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ފާފަފުއްސެވުންއެދި ދެންނެވިއެވެ. އަދި ސަޖިދަށް ތިރިވެވަޑައިގެން ތައުބާ ވެވަޑައިގަތެވެ.","",""],["","","","فغفرنا له ذلك وإن له عندنا لزلفى وحسن مآب","ދެން ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް އެ ފާފަފުއްސެވީމެވެ. އަދި ހަމަކަށަވަރުން، އެކަލޭގެފާނަށް، ތިމަންރަސްކަލާނގެ ހަޒުރަތުގައި ކުއްތަންވުމާއި، އެނބުރިދަނިވި ރިވެތިވެގެންވާ ތަނެއްވެއެވެ.","",""],["","","","يا داوود إنا جعلناك خليفة في الأرض فاحكم بين الناس بالحق ولا تتبع الهوى فيضلك عن سبيل الله إن الذين يضلون عن سبيل الله لهم عذاب شديد بما نسوا يوم الحساب","އޭ ދާވޫދުގެފާނެވެ! ހަމަކަށަވަރުން، ބިމުގައި ޚަލީފާއެއްކަމުގައި ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ލެއްވީމެވެ. ފަހެ، ކަލޭގެފާނު މީސްތަކުންގެ މެދުގައި ހައްގު ގޮތުގައި ހުކުމްކުރައްވާށެވެ! އަދި އަމިއްލައެދުމަށް ކަލޭގެފާނު ތަބާ ވެވަޑައިނުގަންނަވާށެވެ! ފަހެ، އޭރުން ކަލޭގެފާނު ﷲގެ މަގުން އެއްކިބާކޮށްފާނެތެވެ. ހަމަކަށަވަރުން، ﷲގެ މަގުން އެއްކިބާވާމީހުން (ދަންނާށެވެ!) ހިސާބު ބައްލަވާ ދުވަސް ހަނދާންނައްތައިލުމުގެ ސަބަބުން އެއުރެންނަށް ގަދަވެގެންވާ އަޒާބު ހުށްޓެވެ.","",""],["","","","وما خلقنا السماء والأرض وما بينهما باطلا ذلك ظن الذين كفروا فويل للذين كفروا من النار","ތިމަންރަސްކަލާނގެ އުޑާއި، ބިމާއި، އެދެމެދުގައިވާހާ ތަކެތި ބާތިލު ގޮތެއްގައި ނަހައްދަވަމެވެ. އެއީ ކާފިރުވި މީހުން ހީކުރާގޮތެވެ. ފަހެ، ކާފިރުވި މީހުންނަށް، ނަރަކައިގެ އަޒާބުން ހަލާކުހުށްޓެވެ.","",""],["","","","أم نجعل الذين آمنوا وعملوا الصالحات كالمفسدين في الأرض أم نجعل المتقين كالفجار","ނުވަތަ ބިމުގައި ފަސާދައުފައްދާ މީހުންނެކޭ އެއްފަދައިން، ތިމަންރަސްކަލާނގެ، އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަމީހުން ލައްވާނެހެއްޔެވެ؟ ނުވަތަ ކާފިރުވި މީހުންނެކޭ އެއްފަދައިން، ތިމަންރަސްކަލާނގެ ތަގުވާވެރިން ލައްވާނެހެއްޔެވެ؟","",""],["","","","كتاب أنزلناه إليك مبارك ليدبروا آياته وليتذكر أولو الألباب","(މިއީ) ކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ ބާވައިލެއްވި ބަރަކާތް ތެރި ފޮތެކެވެ. (އެއީ) އެއުރެން އެ ފޮތުގެ އާޔަތްތަކުގެ މާނަތަކާމެދު ވިސްނައި ފިކުރުކުރުމަށެވެ. އަދި ބުއްދީގެ އަހުލުވެރިން (އެއިން) ނަސޭހަތް ލިބިގަތުމަށެވެ.","",""],["","","","ووهبنا لداوود سليمان نعم العبد إنه أواب","ތިމަންރަސްކަލާނގެ ދާވޫދުގެފާނަށް ސުލައިމާނުގެފާނު ދެއްވީމެވެ. އެއަޅާގެ ރަނގަޅުކަމާއެވެ! ހަމަކަށަވަރުން، އެކަލޭގެފާނީ، ގިނަގިނައިން ތައުބާ ވެވަޑައިގަންނަވާ ބޭކަލެކެވެ.","",""],["","","","إذ عرض عليه بالعشي الصافنات الجياد","(އެއްދުވަހެއްގެ) ހަވީރުކޮޅުގައި އެކަލޭގެފާނު (އެބަހީ: ސުލައިމާނުގެފާނު) ބެއްލެވުމަށް، ދުވާއިރު ހަލުވި، ހުއްޓި ތިބޭއިރު ހަމަހިމޭން އަސްތައް ހުށަހެޅުނުހިނދު ހަނދުމަކުރާށެވެ!","",""],["","","","فقال إني أحببت حب الخير عن ذكر ربي حتى توارت بالحجاب","ފަހެ، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، އަހުރެންގެ ވެރިރަސްކަލާނގެ ހަނދުމަކޮށް ޛިކުރުކުރުން ފިޔަވައި، އިރު ފަރުދާވެ ނިވައިވެއްޖައުމަށްދާނދެން އަހަށް ލޯބިކުރުން، އަހުރެންނަށް އިސްކުރެވިއްޖެއެވެ.","",""],["","","","ردوها علي فطفق مسحا بالسوق والأعناق","އެ އަސްތައް އަހުރެންގެ ކައިރިޔަށް އަނބުރައި ގެންނާށެވެ! ދެން އެތަކެތީގެ ކަނދުރާގައި (ކަނޑިން) ޖައްސަވައި (ކަތިލައްވައި) ފައިތައް ބުރިކުރެއްވިއެވެ. (އަދި އެތަކެތިން ސަދަގާތްކުރެއްވިއެވެ.)","",""],["","","","ولقد فتنا سليمان وألقينا على كرسيه جسدا ثم أناب","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ސުލައިމާނުގެފާނު އިމްތިހާނުކުރެއްވީމެވެ. އަދި އެކަލޭގެފާނުގެ ތަޚުތުގެ މައްޗަށް ހަށިގަނޑެއް އެއްލެވީމެވެ. ދެން އެކަލޭގެފާނު (ތައުބާ ވެވަޑައިގެން) އެނބުރި ރުޖޫއަ ވެވަޑައިގަތެވެ.","",""],["","","","قال رب اغفر لي وهب لي ملكا لا ينبغي لأحد من بعدي إنك أنت الوهاب","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަޅުގެވެރިރަސްކަލާކޮ! މިއަޅާޔަށް ފާފަފުއްސަވާނދޭވެ! އަދި މިއަޅާގެ ފަހުން އެކަކަށްވެސް އެކަށީގެންނުވާފަދަ ރަސްކަމެއް މިއަޅާޔަށް ދެއްވާނދޭވެ! ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ، ގިނަގުނަ ނިއުމަތްތައް ދެއްވާ ރަސްކަލާނގެއެވެ.","",""],["","","","فسخرنا له الريح تجري بأمره رخاء حيث أصاب","ފަހެ، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް ވައި ޚިދުމަތް ތެރިކޮށްދެއްވީމެވެ. އެކަލޭގެފާނުގެ އަމުރު ފުޅަށް، އެކަލޭގެފާނު އެދިވަޑައިގަތް ކޮންމެތަނަކަށް މައިތިރިކަމާއެކު، އެވައި ހިނގައިދެއެވެ.","",""],["","","","والشياطين كل بناء وغواص","އަދި ޖިންނި ޝައިތާނުން، އެކަލޭގެފާނަށް ޚިދުމަތް ތެރިކޮށް ދެއްވީމެވެ. އޭގެތެރޭގައި (ބޮޑެތި) ބިނާތައްހަދާ ބަޔަކާއި (ކަނޑުގެ އަޑިޔަށް) ފީނާބަޔަކުވެއެވެ.","",""],["","","","وآخرين مقرنين في الأصفاد","އަދި (އޭގެތެރެއިން) އަނެއްބަޔަކު ކަސްތަޅު އަޅުއްވައި ހައްޔަރުކުރައްވާފައިވެއެވެ.","",""],["","","","هذا عطاؤنا فامنن أو أمسك بغير حساب","މިއީ ތިމަންރަސްކަލާނގެ ދެއްވިހާ ތަކެއްޗެވެ. ފަހެ، ކަލޭގެފާނު (ދެއްވާނެ މީހަކަށް) ދެއްވާށެވެ! ނުވަތަ (ނުދެއްވާނެ މީހަކަށް ނުދެއްވައި) ހިފަހައްޓަވާށެވެ! (އެކަމާމެދު) ކަލޭގެފާނާ ސުވާލެއް ނުކުރައްވާނެތެވެ.","",""],["","","","وإن له عندنا لزلفى وحسن مآب","އަދި ހަމަކަށަވަރުން، އެކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ ހަޒުރަތުގައި ކުއްތަންވުމާއި، އެނބުރިދަނިވި ރިވެތިވެގެންވާ ތަނެއްވެއެވެ.","",""],["","","","واذكر عبدنا أيوب إذ نادى ربه أني مسني الشيطان بنصب وعذاب","ތިމަންރަސްކަލާނގެ އަޅު އައްޔޫބުގެފާނު ހަނދުމަކުރައްވާށެވެ! (އެއީ) އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ދުއާ ދެންނެވި ހިނދުގައެވެ. (އެކަލޭގެފާނު ދެންނެވިއެވެ.) އަޅުގެ ގައިގައި ޝައިތާނާ ބީހި، އެކަލޭގެ ފަރާތުން އަޅާއަށް ވަރުބަލިކަމާއި ވޭން ލިބިއްޖެއެވެ.","",""],["","","","اركض برجلك هذا مغتسل بارد وشراب","(އެކަލޭގެފާނަށް އެންގެވިއެވެ.) ކަލޭގެފާނުގެ ފައިންޕުޅުން (ބިމުގައި) ޖައްސަވާށެވެ! (ދެން އެތަނުން ފެންއާރެއް ނުކުތުމުން އެންގެވިއެވެ.) މިއީ ކަލޭގެފާނު ނާނެފިއްލެވުމަށާއި، ހިއްޕެވުމަށްވާ ފިނި (ހިހޫ) ފެނެވެ.","",""],["","","","ووهبنا له أهله ومثلهم معهم رحمة منا وذكرى لأولي الألباب","އަދި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް އެކަލޭގެފާނުގެ އަހުލުވެރިންދެއްވައި، އެއުރެންނާއެކު ހަމައެފަދަ ބަޔަކު ދެއްވީމެވެ. (އެއީ) ތިމަންރަސްކަލާނގެ ހަޒުރަތުން ލެއްވި ރަހުމަތެއް ކަމުގައްޔާއި، ބުއްދީގެ އަހުލުވެރިންނަށްވާ އިބްރަތަކާއި، ނަސޭހަތެއް ކަމުގައެވެ.","",""],["","","","وخذ بيدك ضغثا فاضرب به ولا تحنث إنا وجدناه صابرا نعم العبد إنه أواب","އަދި ކަލޭގެފާނުގެ އަތްޕުޅުން ހުއިބޮނޑިއެއް ނަންގަވައި، އެއިން (އަނބިކަނބަލުންގެ ގައިކޮޅުގައި) ޖައްސަވާށެވެ! ކަލޭގެފާނު ހުވަޔާ ޚިލާފު ވެވަޑައިނުގަންނަވާށެވެ! ހަމަކަށަވަރުން، އެކަލޭގެފާނީ ކެތްތެރިޔަކު ކަމުގައި ތިމަންރަސްކަލާނގެ ދެކެވޮޑިގެންވީމެވެ. އެއަޅާގެ ރަނގަޅުކަމާއެވެ! ހަމަކަށަވަރުން، އެކަލޭގެފާނީ، ގިނަގިނައިން ތައުބާ ވެވަޑައިގަންނަވާ ބޭކަލެކެވެ.","",""],["","","","واذكر عبادنا إبراهيم وإسحاق ويعقوب أولي الأيدي والأبصار","އަދި ތިމަންރަސްކަލާނގެ އަޅުން ކަމުގައިވާ އިބްރާހީމްގެފާނާއި، އިސްޙާގުގެފާނާއި، ޔައުގޫބުގެފާނު ހަނދުމަކުރައްވާށެވެ! (އެބޭކަލުންނީ) ހެޔޮ ޢަމަލުކުރެއްވުމަށް ބާރުގަދަ، ބުއްދީގެ އަހުލުވެރިންނެވެ.","",""],["","","","إنا أخلصناهم بخالصة ذكرى الدار","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެބޭކަލުން ސާފު ޚަޞީލަތަކުން މާތްކުރައްވައި، ޚިޔާރުކުރެއްވީމެވެ. އެއީ އާޚިރަތް ހަނދުމަކުރެއްވުމެވެ.","",""],["","","","وإنهم عندنا لمن المصطفين الأخيار","އަދި ހަމަކަށަވަރުން، އެބޭކަލުންވަނީ، ތިމަންރަސްކަލާނގެ ހަޒުރަތުގައި ޚިޔާރުކުރައްވާފައިވާ ހެޔޮލަފާ ބޭކަލުންގެ ތެރެއިންނެވެ.","",""],["","","","واذكر إسماعيل واليسع وذا الكفل وكل من الأخيار","އަދ އިސްމާޢީލުގެފާނާއި، އަލްޔަސަޢުގެފާނާއި، ޛުލްކިފްލިގެފާނު ހަނދުމަކުރައްވާށެވެ! އެހުރިހާ ބޭކަލުންވަނީ ހެޔޮލަފާމީހުންގެ ތެރެއިންނެވެ.","",""],["","","","هذا ذكر وإن للمتقين لحسن مآب","މިއީ (އެބޭކަލުންނަށްވާ) ރިވެތި ހަނދާން ކުރުމަކާއި، ޝަރަފެކެވެ. އަދި ހަމަކަށަވަރުން، ތަގުވާވެރިންނަށް އެނބުރިދަނިވި ރިވެތިވެގެންވާ ތަނެއްވެއެވެ.","",""],["","","","جنات عدن مفتحة لهم الأبواب","(އެއީ) އެތާނގެ ދޮރުތައް އެއުރެންނަށްޓަކައި ހުޅުވިފައިވާ ޢަދަނެވެ ކިއުނު ސުވަރުގެތަކެވެ.","",""],["","","","متكئين فيها يدعون فيها بفاكهة كثيرة وشراب","އެއުރެން އެތާނގައި (އެނދު އެނދުގައި) ލެނގިލައިގެން ތިބޭނެތެވެ. އެއުރެން އެތާނގައި ގިނަބާވަތް ބާވަތުގެ މޭވާތަކާއި، ބުއިންތައް ގެންނަން އެދޭނެތެވެ.","",""],["","","","وعندهم قاصرات الطرف أتراب","އަދި އެއުރެންނަށް އެއްފުރާގެ އަނބިންތައްވެއެވެ. އެ އަނބިން، ފިރިން ނޫން އެހެންބަޔަކަށް ނުބަލާނެތެވެ.","",""],["","","","هذا ما توعدون ليوم الحساب","މިއީ ހިސާބު ބައްލަވާދުވަހަށް ތިޔަބައިމީހުންނަށް ވައުދުކުރައްވާ ކަންތަކެވެ.","",""],["","","","إن هذا لرزقنا ما له من نفاد","ހަމަކަށަވަރުން، މިއީ ތިމަންރަސްކަލާނގެ ދެއްވާތަކެތިކަން ކަށަވަރެވެ. އެތަކެއްޗަށް ހުސްވުމެއްނުވެއެވެ.","",""],["","","","هذا وإن للطاغين لشر مآب","ކަންހުރިގޮތީ މިއީއެވެ. އަދި ހަމަކަށަވަރުން، ކާފިރުވި މީހުންނަށް އެނބުރިދަނިވި ނުބައިކަންބޮޑުވެގެންވާ ތަނެއްވެއެވެ.","",""],["","","","جهنم يصلونها فبئس المهاد","(އެއީ) ޖަހައްނަމެވެ. އެއުރެން އެތަނަށްވަންނަ ހުށްޓެވެ. ފަހެ، އެ ތަންމަތީގެ ހުރި ނުބައިކަމާއެވެ!","",""],["","","","هذا فليذوقوه حميم وغساق","މިއީ އަޒާބެވެ. ފަހެ، އެއުރެން އޭގެ ރަހަ ލިބިގަންނަހުށިކަމެވެ! (އެއީ) ކެކިކެކިހުރި ހޫނުފެނާއި، ފާދިޔައެވެ.","",""],["","","","وآخر من شكله أزواج","އަދި އެފަދަ އެތައްބާވަތެއްގެ އެހެނިހެން އަޒާބެއުރެންނަށް ހުށްޓެވެ.","",""],["","","","هذا فوج مقتحم معكم لا مرحبا بهم إنهم صالو النار","(އެއުރެންގެ ބޮޑުންނަށް އަންގަވާނެތެވެ.) މިއީ، ތިޔަބައިމީހުންނާއެކު ނަރަޔަކަށްވަންނަ ބައިގަނޑެކެވެ. އެއުރެންނަށް ތަނަވަސްކަމެއްނެތެވެ. ހަމަކަށަވަރުން، އެއުރެންނީ ނަރަކައަށް ވަންނާނެބަޔެކެވެ.","",""],["","","","قالوا بل أنتم لا مرحبا بكم أنتم قدمتموه لنا فبئس القرار","އެ (ތަބާ ވީ) މީހުން ބުނާނެތެވެ. އަދި ކިއެއްތަ! ތިޔަބައިމީހުންނަކަށް ތަނަވަސްކަމެއްނެތެވެ. އެ ކާފިރު ކަން އަހުރެމެންނަށް ކުރިމަތިކޮށްދިނީ ތިޔަބައިމީހުންނެވެ. ފަހެ، އެއީ ތިބުމަށް ހާދަހާނުބައިތަނެކެވެ.","",""],["","","","قالوا ربنا من قدم لنا هذا فزده عذابا ضعفا في النار","އެއުރެން ބުނާނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެންނަށް މިކަން ކުރިމަތިކޮށްދިން މީހުންނަށް ނަރަކައިގައި އަޒާބު ދެބައި އިތުރުކުރައްވާނދޭވެ!","",""],["","","","وقالوا ما لنا لا نرى رجالا كنا نعدهم من الأشرار","އަދި އެއުރެން ބުނާނެތެވެ. (ދުނިޔޭގައި) އަހަރެމެން ނުލަފާމީހުން ކަމުގައި ހިމަނައިއުޅުނު ފިރިހެނުންތައް އަހުރެމެންނަށް މިނުފެންނަނީ ކީއްވެގެންހެއްޔެވެ؟","",""],["","","","أتخذناهم سخريا أم زاغت عنهم الأبصار","އެއުރެންނަށް ތިމަންމެން ފުރައްސާރަކޮށް އުޅުނީހެއްޔެވެ؟ ނުވަތަ އެއުރެން ފިޔަވައި ލޯތައް އެހެންފަރާތަކަށް ލެނބުނީހެއްޔެވެ؟","",""],["","","","إن ذلك لحق تخاصم أهل النار","ހަމަކަށަވަރުން، ނަރަކައިގެ އަހުލުވެރިންގެ އަރާރުމުގެ ވާހަކައަކީ، އެއީ ހައްގު ތެދުކަން ކަށަވަރެވެ.","",""],["","","","قل إنما أنا منذر وما من إله إلا الله الواحد القهار","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނު ވާކަންކަށަވަރީ، އިންޒާރުކުރައްވާ ބޭކަލަކު ކަމުގައެވެ. އަދި އެއްކައުވަންތަ، ބާރުވެރިވަންތަ ﷲ މެނުވީ އެހެން އިލާހަކު ނުވެއެވެ.","",""],["","","","رب السماوات والأرض وما بينهما العزيز الغفار","(އެއީ) އުޑުތަކާއި، ބިމާއި، އެދެމެދުގައިވާހާ ތަކެތީގެ ވެރިރަސްކަލާނގެއެވެ. ޢަޒީޒުވަންތަ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަސްކަލާނގެއެވެ.","",""],["","","","قل هو نبأ عظيم","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއީ (އެބަހީ: ގުރްއާނަކީ) ބޮޑުވެގެންވާ ޚަބަރެކެވެ.","",""],["","","","أنتم عنه معرضون","ތިޔަބައިމީހުންނީ އެއިން އެއްކިބާވާ ބަޔެކެވެ.","",""],["","","","ما كان لي من علم بالملإ الأعلى إذ يختصمون","(އާދަމުގެފާނާމެދު) މަތިވެރިވެގެންވާ ޖަމާއަތްގެ މެދުގައި (އެބަހީ: މަލާއިކަތުންގެ މެދުގައި) ވާހަކަ ދެކެވުނުހިނދު (ވަހީގެ ޛަރީޢާ އިން އެންގެވި އެއްޗެއް މެނުވީ) ތިމަންކަލޭގެފާނަކަށް އެނގިވަޑައިގެންފައެއް ނުވެތެވެ.","",""],["","","","إن يوحى إلي إلا أنما أنا نذير مبين","ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނީ، ބަޔާންވެގެންހުރި، އިންޒާރުކުރައްވާ ބޭކަލަކު ކަމުގައި މެނުވީ، ތިމަންކަލޭގެފާނަކަށް ވަހީއެއް ނުއިއްވަވަތެވެ.","",""],["","","","إذ قال ربك للملائكة إني خالق بشرا من طين","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، މަލާއިކަތުންނަށް ވަހީކުރެއްވިހިނދު ހަނދުމަކުރައްވާށެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، މަށިން އިންސާނަކު ހައްދަވާހުށީމެވެ.","",""],["","","","فإذا سويته ونفخت فيه من روحي فقعوا له ساجدين","ފަހެ، ތިމަންރަސްކަލާނގެ އެ އިންސާނާ (އެބަހީ: އާދަމުގެފާނު) ހައްދަވައި ފުރިހަމަކުރައްވައި، ތިމަންރަސްކަލާނގެ ރޫޙުފުޅުން އެ އިންސާނާއަށް ފުމެލައްވައިފިހިނދު، ތިޔަބައިމީހުން އޭނާއަށްޓަކައި ސަޖިދަށް ތިރިވާހުށިކަމެވެ!","",""],["","","","فسجد الملائكة كلهم أجمعون","ފަހެ، މަލާއިކަތުން، އެ އެންމެން އެކުގައި ސަޖިދަކުރައްވައިފޫއެވެ.","",""],["","","","إلا إبليس استكبر وكان من الكافرين","އިބްލީސް މެނުވީއެވެ. އެކަލޭގެ ބޮޑާވެ، ކާފިރުވި މީހުންގެ ތެރެއިންވިއެވެ.","",""],["","","","قال يا إبليس ما منعك أن تسجد لما خلقت بيدي أستكبرت أم كنت من العالين","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. އޭ އިބްލީސެވެ! ތިމަންރަސްކަލާނގެ އަތްޕުޅުން (އެއްވެސް ވާސިޠަކާނުލައި) ހެއްދެވި މީހަކަށް ސަޖިދަކުރުން ކަލޭގެޔަށް މަނާކުރީ ކޮންކަމެއްހެއްޔެވެ؟ ކަލޭގެ (ސަޖިދަކުރުމަށް) ބޮޑާވެގަތީހެއްޔެވެ؟ ނުވަތަ ކިބުރުވެރިވެގަތް މީހުންގެ ތެރެއިން ކަލޭވީހެއްޔެވެ؟","",""],["","","","قال أنا خير منه خلقتني من نار وخلقته من طين","އެކަލޭގެ ދެންނެވިއެވެ. އެކަލޭގެފާނަށްވުރެ ތިމަން، މާމޮޅެވެ. އިބަރަސްކަލާނގެ ތިމަންހެއްދެވީ އަލިފާނުންނެވެ. އަދި އިބަރަސްކަލާނގެ އެކަލޭގެފާނު ހެއްދެވީ މަށިންނެވެ.","",""],["","","","قال فاخرج منها فإنك رجيم","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ފަހެ، ކަލޭއެތަނުން (އެބަހީ: ސުވަރުގެއިން) ނުކުންނާށެވެ! ފަހެ، ހަމަކަށަވަރުން، ކަލެއަކީ، ރަހުމަތުން ބޭރުކުރައްވާފައިވާ މީހެކެވެ.","",""],["","","","وإن عليك لعنتي إلى يوم الدين","އަދި ހަމަކަށަވަރުން، ގިޔާމަތް ދުވަހަށް ދާނދެން ކަލޭގެމައްޗަށް ތިމަންރަސްކަލާނގެ ލައުނަތް ހުށްޓެވެ.","",""],["","","","قال رب فأنظرني إلى يوم يبعثون","އެކަލޭގެ ދެންނެވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ފަހެ، އެއުރެން (އަލުން ދިރުއްވައި މަހުޝަރަށް) ފޮނުއްވާނޭ ދުވަހަށްދާނދެން ތިމަން އަޅާއަށް މުހުލަތް ދެއްވާނދޭވެ!","",""],["","","","قال فإنك من المنظرين","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ފަހެ، ހަމަކަށަވަރުން، ކަލޭގެވަނީ މުހުލަތް ދެއްވާފައިވާ މީހުންގެ ތެsރެއިންނެވެ.","",""],["","","","إلى يوم الوقت المعلوم","ވަގުތު ކަނޑައެޅި އެނގިގެންވާ ދުވަހަށް ދާނދެނެވެ.","",""],["","","","قال فبعزتك لأغوينهم أجمعين","އެކަލޭގެ ދެންނެވިއެވެ. ފަހެ، އިބަރަސްކަލާނގެ ޢިއްޒަތް ތެރިވަންތަކަން ގަންދީ ބުނަމެވެ. ހަމަކަށަވަރުން، އެއުރެންގެ އެންމެން މަގުފުރައްދާހުށީމެވެ.","",""],["","","","إلا عبادك منهم المخلصين","އެއުރެންކުރެ، އިބަރަސްކަލާނގެ ޚިޔާރުކުރައްވާފައިވާ އަޅުން މެނުވީއެވެ.","",""],["","","","قال فالحق والحق أقول","އެކަލާނގެ ވަހީކުރެއްވިއެވެ. ފަހެ، ތިމަންރަސްކަލާނގެއީ، ހައްގުވަންތަ ރަސްކަލާނގެއެވެ. އަދި ތިމަންރަސްކަލާނގެ ވަހީކުރައްވަނީ ހައްގު ތެދެވެ.","",""],["","","","لأملأن جهنم منك وممن تبعك منهم أجمعين","ހަމަކަށަވަރުން، ކަލޭގެޔާއި އަދި އެއުރެންގެ ތެރެއިން ކަލޭގެޔަށް ތަބާ ވީ ބަޔަކާއި އެ އެންމެންއަޅުއްވައި ނަރަކަ ފުރުއްވާހުށީމެވެ.","",""],["","","","قل ما أسألكم عليه من أجر وما أنا من المتكلفين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަމުގެ މައްޗަށް (އެބަހީ: ރަސޫލު ކަން އިއްވެވުމުގެ މައްޗަށް) ތިމަންކަލޭގެފާނު އެއްވެސް އުޖޫރައެއް ތިޔަބައިމީހުންގެ ކިބަޔަކުން ނޭދެމެވެ. އަދި އަމިއްލަޔަށް ހެދިގަނެގެންއުޅޭ މީހުންގެ ތެރެޔަކުންވެސް އަހުރެން ނުވަމެވެ.","",""],["","","","إن هو إلا ذكر للعالمين","އާލަމް ތަކަށްވާ، ހަނދާންކޮށްދިނުމެއް ކަމުގައި މެނުވީ އެ ގުރްއާން ނުވެއެވެ.","",""],["","","","ولتعلمن نبأه بعد حين","ހިނދުކޮޅެއްގެފަހުން އޭގެ ޚަބަރު (އެބަހީ: އެއީ ތެދުކަން) ނިކަންހުރެ ތިޔަބައިމީހުންނަށް އެނގޭހުށްޓެވެ.","",""],["","","","بسم الله الرحمن الرحيم تنزيل الكتاب من الله العزيز الحكيم","މިއީ ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ﷲގެ ހަޒުރަތުން ބާވައިލެއްވި ފޮތެވެ.","",""],["","","","إنا أنزلنا إليك الكتاب بالحق فاعبد الله مخلصا له الدين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ހައްގު ގޮތުގައި ކަލޭގެފާނުގެ މައްޗަށް ފޮތް ބާވައިލެއްވީމެވެ. ފަހެ، ﷲއަށް ދީން ޚާލިސްކުރާ ޙާލު، ކަލޭގެފާނު އެކަލާނގެއަށް އަޅުކަން ކުރައްވާށެވެ!","",""],["","","","ألا لله الدين الخالص والذين اتخذوا من دونه أولياء ما نعبدهم إلا ليقربونا إلى الله زلفى إن الله يحكم بينهم في ما هم فيه يختلفون إن الله لا يهدي من هو كاذب كفار","ދަންނާށެވެ! ޚާލިސް ވެގެންވާ ދީން ވަނީ ﷲއަށެވެ. އަދި އެކަލާނގެ ފިޔަވައި އެހީތެރިންތަކެއް ހިފިމީހުން ބުނޫއެވެ. ﷲގެ ހަޒުރަތަށް ތިމަންމެން ކުއްތަންކޮށްދިނުމަށްމެނުވީ، ތިމަންމެން އެތަކެއްޗަކަށް (އެބަހީ: ބުދުތަކަށް) އަޅުކަމެއް ނުކުރަމުއެވެ. ހަމަކަށަވަރުން، އެއުރެން އެކަމާމެދު ޚިލާފު ވެގެންއުޅޭ ކަންތަކާދޭތެރޭގައި ﷲ، އެއުރެންގެ މެދުގައި ހުކުމްކުރައްވާނެތެވެ. ހަމަކަށަވަރުން، ދޮގުހަދާ ކާފިރަކަށް ﷲ ތެދުމަގެއް ނުދައްކަވާނެތެވެ.","",""],["","","","لو أراد الله أن يتخذ ولدا لاصطفى مما يخلق ما يشاء سبحانه هو الله الواحد القهار","ﷲ ދަރިކަލަކު ހިއްޕެވުމަށް އިރާދަކުރެއްވިނަމަ، އެކަލާނގެ ހައްދަވާ ތަކެތީގެ ތެރެއިން އެކަލާނގެ އިރާދަކުރައްވާ އެއްޗެއް ޚިޔާރުކުރައްވައިފީހެވެ. އެކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! އެކަލާނގެއީ، އެއްކައުވަންތަ، ބާރުވެރިވަންތަ، ﷲއެވެ.","",""],["","","","خلق السماوات والأرض بالحق يكور الليل على النهار ويكور النهار على الليل وسخر الشمس والقمر كل يجري لأجل مسمى ألا هو العزيز الغفار","އެކަލާނގެ އުޑުތަކާއި، ބިން ހައްގު ގޮތުގައި ހެއްދެވިއެވެ. އެކަލާނގެ ދުވާލުގެ މައްޗަށް ރޭގަނޑު އޮޅައިލައްވަތެވެ. އަދި ރޭގަނޑުގެ މައްޗަށް ދުވާލު އޮޅައިލައްވަތެވެ. އަދި އިރާއިހަނދު ޚިދުމަތް ތެރިކުރެއްވިއެވެ. އެއިންކޮންމެ އެއްޗެއްމެ ކަނޑައެޅިގެންވާ މުއްދަތަކަށް ހިނގާނެތެވެ. ދަންނާށެވެ! އެކަލާނގެއީ، ޢަޒީޒުވަންތަ ރަސްކަލާނގެއެވެ. ގިނަގިނައިން ފާފަފުއްސަވާ ރަސްކަލާނގެއެވެ.","",""],["","","","خلقكم من نفس واحدة ثم جعل منها زوجها وأنزل لكم من الأنعام ثمانية أزواج يخلقكم في بطون أمهاتكم خلقا من بعد خلق في ظلمات ثلاث ذلكم الله ربكم له الملك لا إله إلا هو فأنى تصرفون","އެކަލާނގެ ތިޔަބައިމީހުން ހެއްދެވީ، އެއް ނަފްސަކުންނެވެ. (އެއީ އާދަމުގެފާނެވެ.) ދެން އެ ނަފްސުން އެކަލޭގެފާނުގެ އަނބިކަނބަލުން (ޙައްވާގެފާނު) ހެއްދެވިއެވެ. އަދި ތިޔަބައިމީހުންނަށްޓަކައި، ނަޢަމް ސޫފީގެ އަންހެން ފިރިހެން އަށެތި އުފެއްދެވިއެވެ. ތިޔަބައިމީހުންގެ މައިންގެ ބަނޑުގައި ތިން އަނދިރިކަމެއްގެ ތެރޭގައި، އެއްއުފެއްދެވުމަކަށްފަހު، އަނެއްއުފެއްދެވުމަކުން، އެކަލާނގެ ތިޔަބައިމީހުން ހައްދަވަތެވެ. އެއީ ތިޔަބައިމީހުންގެ ވެރި ﷲއެވެ. ވެރިކަންވަނީ އެކަލާނގެއަށެވެ. އެކަލާނގެ ފިޔަވައި އިލާހަކުނުވެއެވެ. ފަހެ، ތިޔަބައިމީހުން (އެކަލާނގެއަށް އަޅުކަންކުރުން ފިޔަވައި) އެނބުރިދަނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","إن تكفروا فإن الله غني عنكم ولا يرضى لعباده الكفر وإن تشكروا يرضه لكم ولا تزر وازرة وزر أخرى ثم إلى ربكم مرجعكم فينبئكم بما كنتم تعملون إنه عليم بذات الصدور","ތިޔަބައިމީހުން ކާފިރު ވާނަމަ، ފަހެ ﷲއީ، ތިޔަބައިމީހުންގެ ކިބައިންދުރުވެ، ފުދިވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެ އަޅުން ކާފިރު ވުމަކަށް އެކަލާނގެ ނުރުއްސަވަތެވެ. އަދި ތިޔަބައިމީހުން ޝުކުރުކުރާނަމަ، އެކަލާނގެ އެކަމަށް ތިޔަބައިމީހުންނަށް ރުހިވޮޑިގެންވެއެވެ. އަދި ފާފަވެރި އެއްވެސް ނަފްސެއް އެހެން ނަފްސެއްގެ ފާފައެއް ނުއުފުލާނެތެވެ. ދެން ތިޔަބައިމީހުން ރުޖޫއަ ވާހުށީ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށެވެ. ފަހެ، އޭރުން ތިޔަބައިމީހުން ކޮށްއުޅުނު ޢަމަލުތަކުގެ ޚަބަރު، ތިޔަބައިމީހުންނަށް އެކަލާނގެ އަންގަވާނެތެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ހިތްތަކުގައިވާހާ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وإذا مس الإنسان ضر دعا ربه منيبا إليه ثم إذا خوله نعمة منه نسي ما كان يدعو إليه من قبل وجعل لله أندادا ليضل عن سبيله قل تمتع بكفرك قليلا إنك من أصحاب النار","އިންސާނާއަށް އުނދަގުލެއްޖެހޭހިނދު (އެކަމެއް ފިއްލަވާތޯ) އޭނާގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ރުޖޫއަވެ ދުއާކުރެތެވެ. ދެން، އޭނާއަށް ނިއުމަތެއް ދެއްވައިފިނަމަ، އެފަރާތަކަށް އޭނާ ދުއާ ކޮށް އުޅުނުފަރާތް (އެބަހީ: ﷲ) ހަނދާން ނައްތައިލައެވެ. އަދި ﷲއަށް ޝަރީކު ންތަކެއްލައެވެ. އެއީ އެކަލާނގެ މަގުން (މީހުން) ފުރެއްދުމަށެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ކަލޭގެ ތިޔަ ކާފިރުކަމާއެކު ކުޑަދުވަސްކޮޅަކަށް ދުނިޔޭގައި އަރާމުކުރާށެވެ! ހަމަކަށަވަރުން، ކަލޭވަނީ ނަރަކައިގެ އަހުލުވެރިންގެ ތެރެއިންނެވެ.","",""],["","","","أمن هو قانت آناء الليل ساجدا وقائما يحذر الآخرة ويرجو رحمة ربه قل هل يستوي الذين يعلمون والذين لا يعلمون إنما يتذكر أولو الألباب","ރޭގަނޑުގެ ވަގުތުތަކުގައި (ނަމާދުކޮށް) ސަޖިދަ ގައްޔާއި، ގިޔާމްގައި މަޑުމޮޅިވެ، އާޚިރަތް ދުވަހަށް ބިރުވެތިވެ، އޭނާގެ ވެރިރަސްކަލާނގެ ރަހުމަތަށް އެދޭމީހަކު (އެނޫންމީހަކާ) އެއްފަދަވާނެހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ދަންނަމީހުންނާއި، ނުދަންނަމީހުން ހަމަހަމަވާނެ ހެއްޔެވެ؟ ނަސޭހަތް ލިބިގަންނަކަން ކަށަވަރީ، ބުއްދީގެ އަހުލުވެރިންނެވެ.","",""],["","","","قل يا عباد الذين آمنوا اتقوا ربكم للذين أحسنوا في هذه الدنيا حسنة وأرض الله واسعة إنما يوفى الصابرون أجرهم بغير حساب","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ އީމާންވި، ތިމަންރަސްކަލާނގެ އަޅުތަކުންނޭވެ! ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއަށް ތިޔަބައިމީހުން ތަގުވާވެރިވާށެވެ! މިދުނިޔޭގައި ހެޔޮކޮށް ކަންތައްކުޅަމީހުންނަށް ހެޔޮދަރުމަހުށްޓެވެ. އަދި ﷲގެ ބިންވަނީ ތަނަވަސްވެގެންނެވެ. ކެތްތެރިންނަށް އެއުރެންގެ ދަރުމަ ދެއްވާހުށިކަން ކަށަވަރީ ހިސާބެއްނެތިއެވެ.","",""],["","","","قل إني أمرت أن أعبد الله مخلصا له الدين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، އަހުރެންނަށް އަމުރުކުރައްވާފައިވަނީ، ﷲއަށް ދީން ޚާލިސްކުރާ ޙާލު، އެކަލާނގެއަށް އަޅުކަންކުރުމަށެވެ.","",""],["","","","وأمرت لأن أكون أول المسلمين","އަދި އަހުރެންނަށް އަމުރުކުރައްވާފައިވަނީ (މި އުއްމަތްގެ) މުސްލިމުންގެ ތެރެއިން އެންމެފުރަތަމަ މީހާކަމުގައި އަހުރެން ވުމަށެވެ.","",""],["","","","قل إني أخاف إن عصيت ربي عذاب يوم عظيم","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އަހުރެންގެ ވެރިރަސްކަލާނގެއަށް އަހުރެން އުރެދިއްޖެނަމަ، ބޮޑުވެގެންވާ ދުވަހެއްގެ އަޒާބަށް ހަމަކަށަވަރުން، އަހުރެން ބިރުގަންނަމެވެ.","",""],["","","","قل الله أعبد مخلصا له ديني","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަލާނގެއަށް އަހުރެންގެ ދީން ޚާލިސްކުރާ ޙާލު، އަހުރެން އަޅުކަންކުރަނީ، ހަމައެކަނި ﷲއަށެވެ.","",""],["","","","فاعبدوا ما شئتم من دونه قل إن الخاسرين الذين خسروا أنفسهم وأهليهم يوم القيامة ألا ذلك هو الخسران المبين","ފަހެ، އެކަލާނގެ ފިޔަވައި ތިޔަބައިމީހުން އެދޭ އެއްޗަކަށް ތިޔަބައިމީހުން އަޅުކަން ކޮށްބަލާށެވެ! ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ގެއްލުންވެގެންވާ ބަޔަކީ ގިޔާމަތް ދުވަހުން އެއުރެންގެ އަމިއްލަ ނަފްސު ތަކާއި، އެއުރެންގެ އަހުލުވެރިން ގެއްލެނިކުޅަ މީހުންނެވެ. ދަންނާށެވެ! ފާޅުވެ ބަޔާންވެގެންވާ ގެއްލުންވުމަކީ ހަމައެއީއެވެ.","",""],["","","","لهم من فوقهم ظلل من النار ومن تحتهم ظلل ذلك يخوف الله به عباده يا عباد فاتقون","(ނަރަކައިގައި) އެއުރެންނަށް އެއުރެންގެ މަތީގައި އަލިފާނުގެ ފަށަލަތަކެއްވެއެވެ. އަދި އެއުރެންގެ ދަށުގައިވެސް (އަލިފާނުގެ) ފަށަލަތަކެއްވެއެވެ. ﷲ އެތަކެތިން އެކަލާނގެ އަޅުތަކުން ބިރުގަންނަވަތެވެ. އޭ ތިމަންރަސްކަލާނގެ އަޅުތަކުންނޭވެ! ފަހެ، ތިޔަބައިމީހުން، ތިމަންރަސްކަލާނގެއަށް ތަގުވާވެރިވާށެވެ!","",""],["","","","والذين اجتنبوا الطاغوت أن يعبدوها وأنابوا إلى الله لهم البشرى فبشر عباد","ޝައިތާނާއަށް އަޅުކަންކުރުމުން ދުރުވެގަނެ، ﷲގެ ހަޒުރަތަށް ރުޖޫއަ ވާމީހުންނަށް އުފާވެރިކަމުގެ ޚަބަރު ހުށްޓެވެ. ފަހެ، ކަލޭގެފާނު، ތިމަންރަސްކަލާނގެ އަޅުތަކުންނަށް އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާށެވެ!","",""],["","","","الذين يستمعون القول فيتبعون أحسنه أولئك الذين هداهم الله وأولئك هم أولو الألباب","އެއުރެންނީ، ބުނެވޭބަސް އަޑުއަހާ، އޭގެތެރެއިން އެންމެރަނގަޅު ތަކެއްޗަށް ތަބާވާ މީހުންނެވެ. އެއުރެންނަށް ﷲ ތެދުމަގު ދެއްކެވި މީހުންނީ އެއީއެވެ. އަދި ބުއްދީގެ އަހުލުވެރިންނީވެސް، ހަމައެއުރެންނެވެ.","",""],["","","","أفمن حق عليه كلمة العذاب أفأنت تنقذ من في النار","ފަހެ، އަޒާބުގެ ކަލިމަފުޅު ހައްގު ވެއްޖެމީހަކު (އެ އަޒާބުން ކަލޭގެފާނަށް ސަލާމަތް ކުރެއްވޭނެތޯއެވެ؟) ފަހެ، ނަރަކައިގައިވާ މީހަކު ކަލޭގެފާނަށް ސަލާމަތް ކުރެއްވޭނެތޯއެވެ؟","",""],["","","","لكن الذين اتقوا ربهم لهم غرف من فوقها غرف مبنية تجري من تحتها الأنهار وعد الله لا يخلف الله الميعاد","އެހެނެއްކަމަކު، އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ތަގުވާވެރިވިމީހުންނަށް (ސުވަރުގޭގައި) ކޮޓަރިތަކެއްވެއެވެ. އޭގެމަތީގައިވެސް ބިނާކުރައްވާފައިވާ ކޮޓަރިތައްވެއެވެ. އެތާނގެދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުންނާނެތެވެ. އެކަމަށް ﷲ ވަނީ ވައުދުކުރައްވައިފައެވެ. ﷲ ވައުދާ ޚިލާފު ވެވޮޑިއެއް ނުގަންނަވަތެވެ.","",""],["","","","ألم تر أن الله أنزل من السماء ماء فسلكه ينابيع في الأرض ثم يخرج به زرعا مختلفا ألوانه ثم يهيج فتراه مصفرا ثم يجعله حطاما إن في ذلك لذكرى لأولي الألباب","ހަމަކަށަވަރުން، ﷲ އުޑުން ފެން ވެއްސަވައި، ދެން ބިމުގެ ތެރޭގައިވާ ފެންފެންގަނޑަށް އެ ފެން ފޮނުއްވައި، ދެން އެ ފެނުން ކުލަތައް ތަފާތުވެގެންވާ ގޮވާމުގެ ބާވަތްތައް ނެރުއްވާތީ ތިބާ ނުދެކެމުހެއްޔެވެ؟ ދެން އެތަކެތި ހިކި، ރީނދޫކުލައިގައިވާތީ ތިބާއަށް ފެންނާނެތެވެ. ދެން އެކަލާނގެ އެތަކެތި ކުނޑިކުނޑި އެތިއެތިކޮޅުތަކެއް ކަމުގައި ލައްވަތެވެ. ހަމަކަށަވަރުން، އެކަންތަކުގައި ބުއްދީގެ އަހުލުވެރިންނަށް ހަނދާންކޮށްދިނުން ވާކަންކަށަވަރެވެ.","",""],["","","","أفمن شرح الله صدره للإسلام فهو على نور من ربه فويل للقاسية قلوبهم من ذكر الله أولئك في ضلال مبين","ފަހެ، އިސްލާމް ދީނަށް އެމީހެއްގެ ހިތް ތަނަވަސްކޮށްދެއްވައި އޭނާގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ނޫރެއް ލިބިފައިވާމީހަކު (އެނޫންމީހަކާ އެއްފަދަ ހެއްޔެވެ؟) ފަހެ، ﷲ ހަނދާންކުރުން ފިޔަވައި، އެއުރެންގެ ހިތްތައް ހަރުކަށިވެފައިވާ މީހުންނަށް ހަލާކުހުށްޓެވެ. އެއުރެންވަނީ، ފާޅުވެގެންވާ މަގުފުރެދުމެއްގައެވެ.","",""],["","","","الله نزل أحسن الحديث كتابا متشابها مثاني تقشعر منه جلود الذين يخشون ربهم ثم تلين جلودهم وقلوبهم إلى ذكر الله ذلك هدى الله يهدي به من يشاء ومن يضلل الله فما له من هاد","ﷲ، އެންމެ ރިވެތިބަސްތައް ފޮތެއްގެ ސިފައިގައި ބާވައިލެއްވިއެވެ. (ފުރިހަމަކަމުގައި) އެއްފަދަވެގެންވާ، ތަކުރާރުކޮށް ކިޔެވޭ ފޮތަކަށްވާ ޙާލު ގައެވެ. އެ ފޮތް ކިޔެވޭހިނދު، އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ބިރުވެތިވާމީހުންގެ ގައިގެހަންތައް ތުރުތުރު އަޅައިގެންދެއެވެ. ދެން އެއުރެންގެ ގައިގެހަންތަކާއި، ހިތްތައް ﷲ ހަނދުމަކުރުމަށް މަޑުމޮޅިވެދެތެވެ. އެއީ ﷲގެ ތެދުމަގެވެ. އެކަލާނގެ އިރާދަކުރައްވާމީހަކަށް، އެއިން މަގުދައްކަވަތެވެ. އަދި ﷲ މަގުފުރައްދަވާ މީހަކަށް، ފަހެ ތެދުމަގު ދައްކާނޭ ހަމައެކަކުވެސް ނުވެތެވެ.","",""],["","","","أفمن يتقي بوجهه سوء العذاب يوم القيامة وقيل للظالمين ذوقوا ما كنتم تكسبون","ފަހެ، ގިޔާމަތް ދުވަހުން، ގަދަފަދަ އަޒާބަށް އެމީހެއްގެ މޫނު ކުރިމަތިކުރާމީހަކު (އެދުވަހުން އަމާންކަމާއެކު އަންނަމީހަކާ އެއްފަދަވާނޭ ހެއްޔެވެ؟) އަދި އެދުވަހުން އަނިޔާވެރިންނަށް އަންގަވާނެތެވެ. ތިޔަބައިމީހުން ހޯދައިއުޅުނު ޢަމަލުތަކުގެ ރަހަ، ތިޔަބައިމީހުން ލިބިގަންނާށެވެ!","",""],["","","","كذب الذين من قبلهم فأتاهم العذاب من حيث لا يشعرون","އެއުރެންގެ ކުރިން އުޅުނުމީހުންވެސް (ރަސޫލުން) ދޮގުކުރޫއެވެ. ފަހެ، އެއުރެން ހީވެސްނުކުރާ ދިމާޔަކުން، އެއުރެންނަށް އަޒާބު އައެވެ.","",""],["","","","فأذاقهم الله الخزي في الحياة الدنيا ولعذاب الآخرة أكبر لو كانوا يعلمون","ފަހެ، ﷲއެއުރެންނަށް ދުނިޔޭގެ ހަޔާތުގައި ދެރަކަމާއި، ނިކަމެތިކަމުގެ ރަހަ ދެއްކެވިއެވެ. އަދި ހަމަކަށަވަރުން، އާޚިރަތްގެ އަޒާބު މާބޮޑެވެ. އެއުރެންނަށް އެކަން އެނގޭނޭނަމައެވެ.","",""],["","","","ولقد ضربنا للناس في هذا القرآن من كل مثل لعلهم يتذكرون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ މި ގުރްއާންގައި މީސްތަކުންނަށް، ހުރިހާ ބާވަތަކުން މިސާލު ޖެއްސެވީމެވެ. (އެއީ) އެއުރެން ހަނދުމަކުޅައުމަށްޓަކައެވެ.","",""],["","","","قرآنا عربيا غير ذي عوج لعلهم يتقون","އެއްވެސް ގުދުކަމެއްނުވާ، އަރަބި ބަހުން އޮތް ގުރްއާނެއްގެގޮތުގައެވެ. (އެއީ) އެއުރެން ތަގުވާވެރިވުމަށްޓަކައެވެ.","",""],["","","","ضرب الله مثلا رجلا فيه شركاء متشاكسون ورجلا سلما لرجل هل يستويان مثلا الحمد لله بل أكثرهم لا يعلمون","އެއުރެންގެ މެދުގައި ދެކޮޅުވެރިކަން އުފެދިފައިވާ، އެތައްބަޔަކު ބައިވެރިވާ (އަޅު) ފިރިހެނަކާއި ހަމަ އެންމެމީހަކަށް ހާއްސަ ވެގެންވާ (އަޅު) ފިރިހެނެއްގެ މިސާލު ﷲ ޖެއްސެވިއެވެ. މިސާލުގެގޮތުން އެ ދެމީހުން ހަމަހަމަވާނޭ ހެއްޔެވެ؟ ހަމްދު ހުރީ ﷲއަށެވެ. އަދި ކިއެއްތަ! އެއުރެންކުރެ ގިނަމީހުންނަކަށް ނޭނގެތެވެ.","",""],["","","","إنك ميت وإنهم ميتون","ހަމަކަށަވަރުން ކަލޭގެފާނީ، އަވަހާރަވާނޭ ބޭކަލެކެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެންނީވެސް މަރުވާނޭ ބަޔެކެވެ.","",""],["","","","ثم إنكم يوم القيامة عند ربكم تختصمون","ދެން ހަމަކަށަވަރުން ގިޔާމަތް ދުވަހުން ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ތިޔަބައިމީހުން ދެބަސްވެ ވާހަކަދައްކާނޫއެވެ.","",""],["","","","فمن أظلم ممن كذب على الله وكذب بالصدق إذ جاءه أليس في جهنم مثوى للكافرين","ފަހެ، ﷲއާމެދު ދޮގުހަދައި، އަދި ތެދު އެމީހެއްގެގާތަށް އައިހިނދު، އެދޮގުކުރި މީހަކަށްވުރެން، އަނިޔާވެރިކަންބޮޑީ ކާކުހެއްޔެވެ؟ ކާފިރުން ތިބޭނޭތަނެއް ނަރަކައިގައި ނުވޭހެއްޔެވެ؟","",""],["","","","والذي جاء بالصدق وصدق به أولئك هم المتقون","ތެދާއިގެން އަންނަމީހާއާއި އަދި އެތެދު ގަބޫލުކުރާމީހާ (ދަންނާށެވެ!) އެއުރެންނީ، ހަމަ ތަގުވާވެރިންނެވެ.","",""],["","","","لهم ما يشاءون عند ربهم ذلك جزاء المحسنين","އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި އެއުރެން އެދޭހާކަމެއް އެއުރެންނަށް ހުށްޓެވެ. އެއީ އިހްސާން ތެރިންނަށްހުރި ޖަޒާއެވެ.","",""],["","","","ليكفر الله عنهم أسوأ الذي عملوا ويجزيهم أجرهم بأحسن الذي كانوا يعملون","އެއުރެންކޮށްފައިވާ ނުބައި ޢަމަލުތައް، ﷲ، އެއުރެންގެ ކިބައިން ފުއްސެވުމަށްޓަކައެވެ. އަދި އެއުރެން ޢަމަލު ކޮށްއުޅުނު އެންމެހެޔޮގޮތުގެ ދަރުމައިން، އެކަލާނގެ އެއުރެންނަށް ޖަޒާދެއްވުމަށްޓަކައެވެ.","",""],["","","","أليس الله بكاف عبده ويخوفونك بالذين من دونه ومن يضلل الله فما له من هاد","ﷲ، އެކަލާނގެ އަޅާއަށް ފުދޭކަމުގައި ނުވޭހެއްޔެވެ؟ އަދި އެއުރެން އުޅެނީ އެކަލާނގެ ފިޔަވައި އެއުރެން އަޅުކަންކުރާ ތަކެތިން ކަލޭގެފާނު ބިރުގެންނެވުމަށެވެ. އަދި ﷲ މަގުފުރައްދަވާ މީހަކަށް ތެދުމަގުދައްކާނޭ އެކަކުވެސް ނުވެތެވެ.","",""],["","","","ومن يهد الله فما له من مضل أليس الله بعزيز ذي انتقام","އަދި އެމީހަކަށް ﷲ ތެދުމަގު ދައްކަވާމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކު މަގުފުރައްދާނޭ އެކަކުވެސް ނުވެތެވެ. ﷲއީ ޢަޒީޒުވަންތަ، ބަދަލުހިއްޕެވުމުގެ ވެރިރަސްކަލާނގެކަމުގައި ނުވޭހެއްޔެވެ؟","",""],["","","","ولئن سألتهم من خلق السماوات والأرض ليقولن الله قل أفرأيتم ما تدعون من دون الله إن أرادني الله بضر هل هن كاشفات ضره أو أرادني برحمة هل هن ممسكات رحمته قل حسبي الله عليه يتوكل المتوكلون","އަދި ހަމަކަށަވަރުން އުޑުތަކާއި، ބިންހެއްދެވީ ކާކުހޭ ކަލޭގެފާނު އެއުރެންނާ ސުވާލުކުރައްވައިފިނަމަ، އެއުރެން ބުނާނެކަން ކަށަވަރެވެ. ﷲއެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން (ތިމަންކަލޭގެފާނަށް) ޚަބަރު ދީބަލާށެވެ! ﷲ، ތިމަންކަލޭގެފާނަށް ގެއްލުމަކަށް އިރާދަކުރައްވައިފިނަމަ، ﷲ ފިޔަވައި ތިޔަބައިމީހުން އަޅުކަންކުރާ ތަކެއްޗަށް އެ ގެއްލުން ދުރުކޮށްދެވިދާނެހެއްޔެވެ؟ ނުވަތަ އެކަލާނގެ، ތިމަންކަލޭގެފާނަށް ރަހުމަތަކަށް އިރާދަކުރައްވައިފިނަމަ، އެކަލާނގެ ރަހުމަތް (އަޔަނުދީ) އެތަކެއްޗަށް ހިފެހެއްޓިދާނެ ހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނަށް ﷲ ފުދެއެވެ. ވަކީލުކުރާމީހުން ވަކީލުކުރާހުށީ އެކަލާނގެއަށެވެ!","",""],["","","","قل يا قوم اعملوا على مكانتكم إني عامل فسوف تعلمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން ތިބިގޮތުގައި ތިޔަބައިމީހުން ޢަމަލު ކޮށްބަލާށެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުވެސް (ތިމަންކަލޭގެފާނުގެ ގޮތުގައި) ޢަމަލުކުރައްވާހުށީމެވެ. ނިކަމެތިކޮށްލަނިވި އަޒާބު އަންނަހުށީ ކާކަށްކަމާއި، ދެމިހުންނަނިވި އަޒާބު ލިބޭހުށީ ކާކަށްކަންފަހެ، ނިކަންހުރެ ތިޔަބައިމީހުންނަށް އެނގޭނެތެވެ.","",""],["","","","من يأتيه عذاب يخزيه ويحل عليه عذاب مقيم","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން ތިބިގޮތުގައި ތިޔަބައިމީހުން ޢަމަލު ކޮށްބަލާށެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުވެސް (ތިމަންކަލޭގެފާނުގެ ގޮތުގައި) ޢަމަލުކުރައްވާހުށީމެވެ. ނިކަމެތިކޮށްލަނިވި އަޒާބު އަންނަހުށީ ކާކަށްކަމާއި، ދެމިހުންނަނިވި އަޒާބު ލިބޭހުށީ ކާކަށްކަންފަހެ، ނިކަންހުރެ ތިޔަބައިމީހުންނަށް އެނގޭނެތެވެ.","",""],["","","","إنا أنزلنا عليك الكتاب للناس بالحق فمن اهتدى فلنفسه ومن ضل فإنما يضل عليها وما أنت عليهم بوكيل","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ މީސްތަކުންނަށްޓަކައި ހައްގު ތެދާއިގެން ކަލޭގެފާނުގެ މައްޗަށް ފޮތް ބާވައިލެއްވީމެވެ. ފަހެ، ތެދުމަގު ލިބިގެންފިމީހަކު، އެ ތެދުމަގު ލިބިގަންނަނީ އެމީހެއްގެ އަމިއްލަ ނަފްސަށެވެ. އަދި މަގުފުރެދިއްޖެމީހަކު އެ މަގުފުރެދިގަންނަކަން ކަށަވަރީ، އެމީހެއްގެ އަމިއްލަ ނަފްސުގެ މައްޗަށެވެ. އަދި އެއުރެންގެ ކަންތައްތައް ޙަވާލުކުރައްވާފައިވާ ވަކީލަކު ކަމުގައި ކަލޭގެފާނު ނުވެއެވެ.","",""],["","","","الله يتوفى الأنفس حين موتها والتي لم تمت في منامها فيمسك التي قضى عليها الموت ويرسل الأخرى إلى أجل مسمى إن في ذلك لآيات لقوم يتفكرون","ނަފްސުތައް މަރުވާހިނދު، އެ ނަފްސުތަކުގެ ފުރާނަތަކާއި، މަރުނުވެ ނިދާވަގުތުގައި ނިދާމީހުންގެ ފުރާނަތައް ހިއްޕަވަނީ ﷲއެވެ. ދެން މަރުވުމަށް ކަނޑައަޅުއްވައިފިމީހެއްގެ ފުރާނަ، އެކަލާނގެ ހިފަހައްޓަވަތެވެ. އަދި އެނޫންމީހުންގެ ފުރާނަ، ކަނޑައެޅިގެންވާ މުއްދަތަކަށް (ހަށިތަކަށް) ފޮނުއްވަތެވެ. ހަމަކަށަވަރުން، އެކަންތަކުގައި ފިކުރުކުރާ ބަޔަކަށް ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","أم اتخذوا من دون الله شفعاء قل أولو كانوا لا يملكون شيئا ولا يعقلون","ނުވަތަ އެއުރެން، ﷲ ފިޔަވައި އެހެން ޝަފާއަތް ތެރިންތަކެއް ހޯދީހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެ ޝަފާއަތް ތެރިންނަށް އެއްވެސް އެއްޗެއް މިލްކުވެގެންނުވާ، އަދި ބުއްދިއެއް ނުވާނަމަވެސް ހެއްޔެވެ؟","",""],["","","","قل لله الشفاعة جميعا له ملك السماوات والأرض ثم إليه ترجعون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ޝަފާއަތް ތެރިކަންވަނީ، މުޅިންވެސް ﷲއަށެވެ. އުޑުތަކާއި ބިމުގެވެރިކަން ވަނީވެސް އެކަލާނގެއަށެވެ. ދެން ތިޔަބައިމީހުން ރުޖޫއަކުރައްވާހުށީ، އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","وإذا ذكر الله وحده اشمأزت قلوب الذين لا يؤمنون بالآخرة وإذا ذكر الذين من دونه إذا هم يستبشرون","ހަމައެކަނި ﷲގެ އިސްމުފުޅު ނަންގަނެވޭހިނދު، އާޚިރަތަށް އީމާން ނުވާމީހުންގެ ހިތްތަކަށް ފޫހިކަމާއި، ނަފްރަތު ކަން ލިބިގެންދެތެވެ. އަދި އެކަލާނގެ ފިޔަވައި އެހެންތަކެތީގެ ނަން (އެބަހީ: ބުދުތަކުގެނަން) ގަނެވިއްޖެނަމަ، އެހާރުން އެއުރެން އުފާވެގެންދެތެވެ.","",""],["","","","قل اللهم فاطر السماوات والأرض عالم الغيب والشهادة أنت تحكم بين عبادك في ما كانوا فيه يختلفون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ ހައްދަވާ ބޮޑުކުރެއްވި ރަސްކަލާކޮ! އިސްވެދިޔަ މިސާލަކާނުލައި އުޑުތަކާއި، ބިންތައް ހެއްދެވި ރަސްކަލާކޮ! ނުފެންނަ ކަންތަކާއި، ފެންނަކަންތައް ދެނެވޮޑިގެންވާ ރަސްކަލާކޮ! އިބަރަސްކަލާނގެ އަޅުތަކުންގެ މެދުގައި، އެއުރެން ޚިލާފު ވެގެންއުޅުނު ކަންތަކުގެ މައްޗަށް ނިޔާކުރައްވާނީ އިބަރަސްކަލާނގެއެވެ.","",""],["","","","ولو أن للذين ظلموا ما في الأرض جميعا ومثله معه لافتدوا به من سوء العذاب يوم القيامة وبدا لهم من الله ما لم يكونوا يحتسبون","އަނިޔާވެރިވި މީހުންނަށް، ބިމުގައިވާހާ ތަކެއްޗާއި، އެޔާއެކު އެޔާއެއްފަދަ ތަކެތި ލިބުނުކަމުގައިވީނަމަ، ގިޔާމަތް ދުވަހުގެ ގަދަފަދަ އަޒާބުން މުއްތިވުމަށްޓަކައި، އެއިން ފިދުޔަ ދިނީހެވެ. އަދި އެއުރެން ހީވެސްނުކުރާ ކަންތައް އެދުވަހުން ﷲގެ ހަޒުރަތުން އެއުރެންނަށް ފާޅުވާނެތެވެ.","",""],["","","","وبدا لهم سيئات ما كسبوا وحاق بهم ما كانوا به يستهزئون","އެއުރެންހޯދި ނުބައި ޢަމަލުތަކުގެ ޖަޒާ އެއުރެންނަށް ފާޅުވާހުށްޓެވެ. އަދި އެއުރެން ފުރައްސާރަކޮށްއުޅުނު ކަންތައްތައް (އެބަހީ: އެކަމުގެ އަޒާބު) އެއުރެން ވަށައިލާހުށްޓެވެ.","",""],["","","","فإذا مس الإنسان ضر دعانا ثم إذا خولناه نعمة منا قال إنما أوتيته على علم بل هي فتنة ولكن أكثرهم لا يعلمون","ފަހެ، އިންސާނާއަށް އުނދަގުލެއް ޖެހޭހިނދު، ތިމަންރަސްކަލާނގެއަށް އޭނާ ދުއާކުރެތެވެ. ދެން ތިމަންރަސްކަލާނގެ ހަޒުރަތުން އޭނާޔަށް ނިއުމަތެއް ދެއްވައިފިނަމަ، އޭނާ ބުނެތެވެ. ތިމަންނައަށް އެ ނިއުމަތް ލިބިފައިވާކަން ކަށަވަރީ، ތިމަންގެ އިލްމުވެރިކަމުގެ ސަބަބުންނެވެ. އަދި ކިއެއްތަ! އެއީ އިމްތިހާނެކެވެ. އެހެނެއްކަމަކު، އެއުރެންކުރެ ގިނަމީހުންނަކަށް (އެކަމެއް) ނޭނގެތެވެ.","",""],["","","","قد قالها الذين من قبلهم فما أغنى عنهم ما كانوا يكسبون","އެއުރެންގެކުރިން އުޅުނުމީހުންވެސް، ހަމައެފަދައިން ބުނެފައިވެއެވެ. ފަހެ، އެއުރެން ހޯދައިއުޅުނު މަންފާތައް، އެއުރެންނަކަށް އެއްވެސްކަމެއް ފުއްދައެއްނުދިނެވެ.","",""],["","","","فأصابهم سيئات ما كسبوا والذين ظلموا من هؤلاء سيصيبهم سيئات ما كسبوا وما هم بمعجزين","ފަހެ، އެއުރެންހޯދި ނުބައި ޢަމަލުތަކުގެ ޖަޒާ، އެއުރެންގެ މައްޗަށް އައިސްޖެހުނެވެ. އަދި މިބައިމީހުންކުރެ (އެބަހީ: މައްކާގެ މުޝްރިކު ންކުރެ) އަނިޔާވެރިވިމީހުންހޯދި ނުބައި ޢަމަލުތަކުގެ ޖަޒާ ނިކަންހުރެ، އެއުރެންގެ މައްޗަށް އައިސްޖެހޭނެއެވެ. އަދި (ﷲ) ނުކުޅައްދައި ރެކިގެން ދެވޭނޭބަޔަކު ކަމުގައި އެއުރެން ނުވެތެވެ.","",""],["","","","أولم يعلموا أن الله يبسط الرزق لمن يشاء ويقدر إن في ذلك لآيات لقوم يؤمنون","އަދި ހަމަކަށަވަރުން، ﷲ އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ރިޒްގު ތަނަވަސްކުރައްވައި، އަދި (އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ރިޒްގު) ދަތިކުރައްވާކަން އެއުރެން ނުދަންނަނީ ހެއްޔެވެ؟ ހަމަކަށަވަރުން، އީމާންވާ ބަޔަކަށް އެކަމުގައި ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","قل يا عبادي الذين أسرفوا على أنفسهم لا تقنطوا من رحمة الله إن الله يغفر الذنوب جميعا إنه هو الغفور الرحيم","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއުރެންގެ އަމިއްލަ ނަފްސުތަކުގެ މައްޗަށް ފާފައިން އިސްރާފު ކޮށްފައިވާ، ތިމަންރަސްކަލާނގެ އަޅުތަކުންނޭވެ! ތިޔަބައިމީހުން ﷲގެ ރަހުމަތުން އުންމީދު ކަނޑައިނުލާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، އެންމެހާ ފާފަތައްފުއްސަވާ ރަސްކަލާނގެއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وأنيبوا إلى ربكم وأسلموا له من قبل أن يأتيكم العذاب ثم لا تنصرون","އަދި ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއަށް ތައުބާވެ، އެކަލާނގެއަށް ކިޔަމަންވާށެވެ! (އެއީ) ތިޔަބައިމީހުންނަށް އަޒާބު އައުމުގެ ކުރިންނެވެ. ދެން ތިޔަބައިމީހުންނަކަށް ނަސްރެއް ނުލިބޭނެތެވެ.","",""],["","","","واتبعوا أحسن ما أنزل إليكم من ربكم من قبل أن يأتيكم العذاب بغتة وأنتم لا تشعرون","އަދި ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ތިޔަބައިމީހުންނަށް ބާވައިލެއްވި އެންމެމޮޅު ވަހީއަށް (އެބަހީ: ގުރްއާނަށް) ތިޔަބައިމީހުން ތަބާ ވާށެވެ! ތިޔަބައިމީހުންނަށް ނުވެސްއެނގި ތިއްބައި، ކުއްލިޔަކަށް ތިޔަބައިމީހުންނަށް އަޒާބު އައުމުގެ ކުރިންނެވެ.","",""],["","","","أن تقول نفس يا حسرتى على ما فرطت في جنب الله وإن كنت لمن الساخرين","ﷲގެ ފަރާތަށް (އަދާކުރަންޖެހޭ ވާޖިބުތަކުގައި) މިއަޅާ ފަރުވާކުޑަކުރި ކަމަށްޓަކައި، މިއަޅާޔަށްހުރި ހިތާމައިގެ ބޮޑުކަމާއޭ ތިޔަބައިމީހުންކުރެ މީހަކަށް ބުނަންޖެހިދާނެތީއެވެ. އަދި ހަމަކަށަވަރުން، މިއަޅާވީ (ދީނަށް) ފުރައްސާރަކުރާ މީހުންގެ ތެރެއިންނެވެ.","",""],["","","","أو تقول لو أن الله هداني لكنت من المتقين","ނުވަތަ ﷲ މިއަޅާޔަށް ތެދުމަގު ދެއްކެވިނަމަ، މިއަޅާވީހީ، ތަގުވާވެރިންގެ ތެރެއިންކަން ކަށަވަރޭ އެމީހަކު ބުނަންޖެހިދާނެތީއެވެ.","",""],["","","","أو تقول حين ترى العذاب لو أن لي كرة فأكون من المحسنين","ނުވަތަ އެމީހަކަށް އަޒާބު ފެނިގެން އަންނަހިނދު، މިއަޅާޔަށް އަދި އެއްފަހަރު (ދުނިޔެއަށް) ރުޖޫއަ ވުމެއް ލިބޭނެނަމައޭ ބުނަންޖެހިދާނެތީއެވެ. ފަހެ، އޭރުން ތިމަންއަޅާ ވާހުށީ، އިހްސާން ތެރިންގެ ތެރެއިންނެވެ.","",""],["","","","بلى قد جاءتك آياتي فكذبت بها واستكبرت وكنت من الكافرين","އެހެންނަކުންނޫނެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އާޔަތްތައް ކަލޭގެ ގާތަށްއައެވެ. ފަހެ، ކަލޭ އެ އާޔަތްތައް ދޮގުކުރީމުއެވެ. އަދި ބޮޑާވެގަތީމުއެވެ. އަދި ކަލޭވީ، ކާފިރުންގެ ތެރެއިންނެވެ.","",""],["","","","ويوم القيامة ترى الذين كذبوا على الله وجوههم مسودة أليس في جهنم مثوى للمتكبرين","ﷲއަށް ދޮގުހެދިމީހުންގެ މޫނުތައް އަނދިރިވެގެންވާތީ، ގިޔާމަތް ދުވަހުން ކަލޭ ދެކޭނޫއެވެ. ކިބުރުވެރިން ތިބޭނެތަނެއް ނަރަކައިގައި ނުވޭހެއްޔެވެ؟","",""],["","","","وينجي الله الذين اتقوا بمفازتهم لا يمسهم السوء ولا هم يحزنون","އަދި ﷲ، ތަގުވާވެރިވިމީހުން އެއުރެންގެ ކާމިޔާބީއާއެކު ސަލާމަތްކުރައްވާ ހުށްޓެވެ. އެއުރެންނަކަށް އެއްވެސްކަހަލަ ނުބައިކަމެއް ނުޖެހޭނެތެވެ. އަދި ހިތާމަކުރާނޭ ބަޔަކު ކަމުގައިވެސް އެއުރެން ނުވެއެވެ.","",""],["","","","الله خالق كل شيء وهو على كل شيء وكيل","ﷲއީ، ހުރިހާއެއްޗެއް ހައްދަވާ ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެއީ، ކޮންމެކަމެއްގެ މައްޗަށް ބައްލަވާވޮޑިގެންވާ، ރައްކާތެރިކުރައްވާ ރަސްކަލާނގެއެވެ.","",""],["","","","له مقاليد السماوات والأرض والذين كفروا بآيات الله أولئك هم الخاسرون","އުޑުތަކާއި، ބިމުގެ ތަޅުދަނޑިތައް މިލްކުވެވޮޑިގެންވަނީ އެކަލާނގެއަށެވެ. އަދި ﷲގެ އާޔަތްތަކަށް ކާފިރު ވިމީހުން (ދަންނާށެވެ!) ގެއްލެނިވެގެންވާ މީހުންނީ، ހަމައެއުރެންނެވެ.","",""],["","","","قل أفغير الله تأمروني أعبد أيها الجاهلون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ ޖާހިލު ތަކުންނޭވެ! ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނަށް ތިޔައަމުރުކުރަނީ، ﷲ ނޫންފަރާތަކަށް އަޅުކަންކުރުމަށް ހެއްޔެވެ؟","",""],["","","","ولقد أوحي إليك وإلى الذين من قبلك لئن أشركت ليحبطن عملك ولتكونن من الخاسرين","ހަމަކަށަވަރުން، ކަލޭގެފާނަށާއި، ކަލޭގެފާނުގެ ކުރީގެ ރަސޫލުންނަށް ވަހީކުރައްވާފައިވެއެވެ. ކަލޭގެފާނު ޝަރީކުކުރައްވައިފިނަމަ، ކަލޭގެފާނުގެ ޢަމަލުތައް ބާތިލު ވެއްޖައީސްކަން ކަށަވަރެވެ. އަދި އޭރުން ކަލޭގެފާނު ވާހުށީ ގެއްލެނިވެގެންވާ މީހުންގެ ތެރެއިންކަން ކަށަވަރެވެ.","",""],["","","","بل الله فاعبد وكن من الشاكرين","އަދި ކިއެއްތަ! ހަމައެކަނި ﷲއަށް ކަލޭގެފާނު އަޅުކަންކުރައްވާށެވެ! އަދި ޝުކުރުކުރާމީހުންގެ ތެރެއިން ކަލޭގެފާނު ވެވަޑައިގަންނަވާށެވެ!","",""],["","","","وما قدروا الله حق قدره والأرض جميعا قبضته يوم القيامة والسماوات مطويات بيمينه سبحانه وتعالى عما يشركون","ﷲއަށް ގަދަރުކުރުން ހައްގު ވެގެންވާގޮތުގައި، އެއުރެން އެކަލާނގެއަށް ގަދަރެއް ނުކުރެތެވެ. އަދި ގިޔާމަތް ދުވަހުން، މުޅިބިންވާހުށީ، އެކަލާނގެ ކަނާތްޕުޅުގެ ތެރޭގައެވެ. އަދި އުޑުތައްވާހުށީ، ފަށްޖަހައިލައްވާފައިވާ ޙާލު، އެކަލާނގެ ގުދުރަތް ތެރިކަމުގެ ކަނާތްޕުޅުގައެވެ. އެއުރެން ޝަރީކުކުރާ ތަކެތިން، އެކަލާނގެ ހުސްތާހިރުވެ، މަތިވެރިވެވޮޑިގެންވެއެވެ.","",""],["","","","ونفخ في الصور فصعق من في السماوات ومن في الأرض إلا من شاء الله ثم نفخ فيه أخرى فإذا هم قيام ينظرون","ތާޅަފިލި ފުމެލައްވާހުށްޓެވެ. ދެން އުޑުތަކާއި، ބިމުގައިވާހާ ބަޔަކު ހޭނެތި މަރުވެދާހުށްޓެވެ. ﷲ އިރާދަކުރެއްވި މީހަކު މެނުވީއެވެ. ދެން އަނެއްފަހަރު ފުމެލައްވާހުށްޓެވެ. ފަހެ، އެހާރުން އެއުރެން ތެދުވެ (މަހުޝަރު ބިމުގައި) ބަލަބަލައި ތިބޭނެތެވެ.","",""],["","","","وأشرقت الأرض بنور ربها ووضع الكتاب وجيء بالنبيين والشهداء وقضي بينهم بالحق وهم لا يظلمون","އަދި ބިން، އެ ބިމުގެ ވެރިރަސްކަލާނގެ ނޫރުފުޅުން އަލިވެގެންދާނެތެވެ. އަދި ޢަމަލުތަކުގެ ފަތް (ހުޅުވާލައްވާފައި) ބާއްވަވާނެތެވެ. އަދި ނަބިއްޔުންނާއި، ހެކިވެރިން ޙާޒިރުުކުރައްވާނެތެވެ. އަދި އެއުރެންގެ މެދުގައި ހައްގަށް ނިޔާކުރައްވާނެތެވެ. އަދި އެއުރެންނަކަށް ބޭއިންސާފެއް ނުކުރައްވާހުށްޓެވެ.","",""],["","","","ووفيت كل نفس ما عملت وهو أعلم بما يفعلون","އަދި ކޮންމެ ނަފްސަކަށްމެ، އެ ނަފްސެއް ކޮށްފައިވާ ޢަމަލެއް (ގެ ޖަޒާ) ފުރިހަމަޔަށް ލިބޭނެތެވެ. އެކަލާނގެއީ، އެއުރެން ކުރާކަންތައް އެންމެމޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وسيق الذين كفروا إلى جهنم زمرا حتى إذا جاءوها فتحت أبوابها وقال لهم خزنتها ألم يأتكم رسل منكم يتلون عليكم آيات ربكم وينذرونكم لقاء يومكم هذا قالوا بلى ولكن حقت كلمة العذاب على الكافرين","އަދި ކާފިރު ވިމީހުން ބައިބަޔަށް ނަރަކަޔާދިމާއަށް ލަވައި ގެންދަވާނެތެވެ. އެއުރެންނަށް ނަރަކައިގެ ކައިރިޔަށް އާދެވޭހިނދު، އެތާނގެ ދޮރުތައް ހުޅުއްވާނެތެވެ. އަދި އެ ނަރަކައިގެ ބަނޑޭރިން، އެއުރެންނަށް ވިދާޅުވާނެތެވެ. ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ އާޔަތްތައް، ތިޔަބައިމީހުންނަށް ކިޔައިދެއްވާނޭ، އަދި ތިޔަބައިމީހުން މިދުވަހާ ބައްދަލުވާނޭކަމުގެ އިންޒާރުކުރައްވާނޭ ރަސޫލުން ތިޔަބައިމީހުންގެ ތެރެއިން، ތިޔަބައިމީހުންގެ ގާތަކަށް ވަޑައެއްނުގަނޭހެއްޔެވެ؟ އެއުރެން ދަންނަވާނެތެވެ. އެހެންނަކުންނޫނެވެ. (ވަޑައިގަތެވެ.) އެހެނެއްކަމަކު، އަޒާބުގެ ބަސްފުޅު ކާފިރުންގެ މައްޗަށް ހައްގު ވެއްޖެއެވެ.","",""],["","","","قيل ادخلوا أبواب جهنم خالدين فيها فبئس مثوى المتكبرين","އަންގަވާހުށްޓެވެ. އެތާނގައި ދެމިތިބެނިވިގޮތުގައި، ތިޔަބައިމީހުން ނަރަކައިގެ ދޮރުތަކުން ވަންނާށެވެ! ފަހެ (އެއީ) ކިބުރުވެރިވެގެންވާމީހުން ތިބުމަށް ހާދަހާ ނުބައިވެގެންވާ ތަނެކެވެ.","",""],["","","","وسيق الذين اتقوا ربهم إلى الجنة زمرا حتى إذا جاءوها وفتحت أبوابها وقال لهم خزنتها سلام عليكم طبتم فادخلوها خالدين","އަދި އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ތަގުވާވެރިވިމީހުން، ބައިބަޔަށް ސުވަރުގެޔާދިމާއަށް (މާތްކޮށް ހިތުމާއެކު) ލަވައި ގެންދަވާނެތެވެ. އަދި އެ ސުވަރުގޭގެ ކައިރިޔަށް، އެއުރެންނަށް އާދެވޭހިނދު، އެތާނގެ ދޮރުތައް ހުޅުއްވާފައި ހުންނާނެތެވެ. އަދި އެތާނގެ ބަނޑޭރިން އެއުރެންނަށް ވިދާޅުވާނެތެވެ. ތިޔަބައިމީހުންގެ މައްޗަށް ސަލާމް ހުށްޓެވެ. ތިޔަބައިމީހުން ރަނގަޅަށް އުޅެފީމުއެވެ. ފަހެ، އެ ސުވަރުގޭގައި ދެމިތިބެނިވިގޮތުގައި ތިޔަބައިމީހުން އެތަނަށް ވަންނާށެވެ!","",""],["","","","وقالوا الحمد لله الذي صدقنا وعده وأورثنا الأرض نتبوأ من الجنة حيث نشاء فنعم أجر العاملين","އަދި އެއުރެން ބުނާނެތެވެ. ހަމްދު ހުރީ ﷲއަށެވެ. އެކަލާނގެއީ، އަޅަމެންނަށް އެކަލާނގެ ކުރެއްވި ވައުދު ތެދުކުރެއްވި ރަސްކަލާނގެއެވެ. އަދި އަޅަމެން އެދޭތަނެއްގައި ސުވަރުގޭގައި ތިބުމަށް އެކަލާނގެ އަޅަމެންނަށް ސުވަރުގޭގެ ބިން ވާރުތަކުރެއްވިއެވެ. ފަހެ، ހެޔޮ ޢަމަލުކުރާމީހުންނަށްހުރި ދަރުމައިގެ މޮޅުކަމާއެވެ!","",""],["","","","وترى الملائكة حافين من حول العرش يسبحون بحمد ربهم وقضي بينهم بالحق وقيل الحمد لله رب العالمين","އަދި މަލާއިކަތުން އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ހަމްދާއެކު ތަސްބީހަ ދަންނަވާ ޙާލު، ޢަރްޝުގެ ވަށައިގެން ތިއްބަވާތީ ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނޫއެވެ. އަދި އެއުރެންގެ މެދުގައި (އެބަހީ: އެންމެހާ އަޅުތަކުންގެ މެދުގައި) ހައްގަށް ނިޔާކުރައްވާނެތެވެ. އަދި އަންގަވާނެތެވެ. ހަމްދު ހުރީ އާލަމް ތަކުގެވެރި ﷲއަށެވެ.","",""],["","","","بسم الله الرحمن الرحيم حم","ح م (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","تنزيل الكتاب من الله العزيز العليم","މިއީ ޢަޒީޒުވަންތަ، މޮޅަށް ދެނެވޮޑިގެންވާ ﷲގެ ހަޒުރަތުން ބާވައިލެއްވި ފޮތެވެ.","",""],["","","","غافر الذنب وقابل التوب شديد العقاب ذي الطول لا إله إلا هو إليه المصير","(އެކަލާނގެއީ) ފާފަފުއްސަވާ، ތައުބާ ގަބޫލުކުރައްވާ، އުގޫބާތް ގަދަފަދަ، ނިއުމަތްތަކުގެ ވެރިރަސްކަލާނގެއެވެ. އެކަލާނގެ މެނުވީ އިލާހަކު ނުވެއެވެ. (އެންމެހާ ތަކެތި) ރުޖޫއަ ވުންވަނީ އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","ما يجادل في آيات الله إلا الذين كفروا فلا يغررك تقلبهم في البلاد","ކާފިރު ވިމީހުން މެނުވީ، ﷲގެ އާޔަތް ތަކާމެދު ޖަދަލުކޮށެއް ނަހަދަތެވެ. ފަހެ، އެއުރެން ރަށްތަކުގައި އެގޮތްމިގޮތަށް އުޅުން (އެބަހީ: އެއުރެން ހިތުހުރިގޮތަކަށް އުފަލާއި އަރާމުގައި އުޅުން) ކަލޭގެފާނު ހެއްލުންތެރިކުރުވިޔަ ނުދޭހުށިކަމެވެ.","",""],["","","","كذبت قبلهم قوم نوح والأحزاب من بعدهم وهمت كل أمة برسولهم ليأخذوه وجادلوا بالباطل ليدحضوا به الحق فأخذتهم فكيف كان عقاب","އެއުރެންގެ ކުރިން ނޫޙުގެފާނުގެ ގައުމުގެމީހުންނާއި، އޭގެފަހުންވެސް ގުޅިގެން އުޅުނު ޖަމާއަތްތަކުގެ މީހުން (ރަސޫލުން) ދޮގުކުޅައޫއެވެ. އަދި ކޮންމެ އުއްމަތެއްގެ ބަޔަކު، އެބަޔެއްގެ ރަސޫލަކު (ނެތިކޮށްލުމަށްޓަކައި) އަތުލައިގަތުމަށް އުޅުނޫއެވެ. އަދި އެބައިމީހުން ބާތިލު ގޮތުގައި (ރަސޫލުންނާ) ޖަދަލުކުރޫއެވެ. (އެއީ) އެ ބާތިލު ގޮތް މެދުވެރިކޮށް ހައްގު ގޮތް ނައްތައިލުމަށެވެ. ދެން ތިމަންރަސްކަލާނގެ އުގޫބާތް ދެއްވައި، އެއުރެން ހިއްޕެވީމެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ އުގޫބާތް ދެއްވުންވީ، ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","وكذلك حقت كلمت ربك على الذين كفروا أنهم أصحاب النار","ކާފިރު ވިމީހުންގެ މައްޗަށް، ހަމަކަށަވަރުން، އެއުރެންނަކީ، ނަރަކައިގެ އަހުލުވެރިންކަމަށް ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ކަލިމަފުޅު ހައްގު ވެގެންވަނީ އެފަދައިންނެވެ.","",""],["","","","الذين يحملون العرش ومن حوله يسبحون بحمد ربهم ويؤمنون به ويستغفرون للذين آمنوا ربنا وسعت كل شيء رحمة وعلما فاغفر للذين تابوا واتبعوا سبيلك وقهم عذاب الجحيم","ޢަރްޝު އުފުއްލަވާ މަލާއިކަތްނާއި، އޭގެވަށައިގެންވާ މަލާއިކަތުން އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ހަމްދާއެކު ތަސްބީހަ ދަންނަވަތެވެ. އަދި އެކަލާނގެއަށް އީމާން ވެތެވެ. އަދި އީމާން ވިމީހުންނަށް ފާފަފުއްސެވުމަށް ދުއާކުރައްވަތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އިބަރަސްކަލާނގެ ރަހުމަތާއި، ދެނެވޮޑިގަތުން ހުރިހާ އެއްޗެއްގެ މައްޗަށް ތަނަވަސްވެގެންވެއެވެ. ފަހެ، ތައުބާވެ، އިބަރަސްކަލާނގެ މަގަށް ތަބާ ވީ މީހުންނަށް ފާފަފުއްސަވާނދޭވެ! އަދި ނަރަކައިގެ އަޒާބުން އެއުރެން މުއްތިކުރައްވާނދޭވެ!","",""],["","","","ربنا وأدخلهم جنات عدن التي وعدتهم ومن صلح من آبائهم وأزواجهم وذرياتهم إنك أنت العزيز الحكيم","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އެއުރެންނަށް އިބަރަސްކަލާނގެ ވައުދުކުރައްވާފައިވާ ޢަދްނެވެ ކިޔުނު ސުވަރުގެތަކަށް އެއުރެން ވައްދަވާނދޭވެ! އެއުރެންގެ މައިންބަފައިންނާއި، އެއުރެންގެ އަނބީންނާއި، އެއުރެންގެ ދަރިންކުރެ ސާލިހުވި މީހުންނާ އެކުގައެވެ. ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وقهم السيئات ومن تق السيئات يومئذ فقد رحمته وذلك هو الفوز العظيم","އަދި ނުބައިކަންތަކުން އެއުރެން ސަލާމަތްކުރައްވާނދޭވެ! އަދި އިބަރަސްކަލާނގެ އެދުވަހުން، ނުބައިކަމުން ސަލާމަތްކުރައްވާ މީހަކީ، އިބަރަސްކަލާނގެ ރަހުމަތް ލެއްވި މީހެއްކަން ކަށަވަރެވެ. ބޮޑުވެގެންވާ ނަސީބު ލިބުމަކީ ހަމައެއީއެވެ.","",""],["","","","إن الذين كفروا ينادون لمقت الله أكبر من مقتكم أنفسكم إذ تدعون إلى الإيمان فتكفرون","ހަމަކަށަވަރުން، ކާފިރު ވިމީހުންނަށް (އެދުވަހުން) ގޮވައިލައްވާނެތެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތަކަށް ތިޔަބައިމީހުން ނަފުރަތުވާ ވަރަށްވުރެ، ﷲގެ ކޯފާވެވޮޑިގަތުން މާބޮޑެވެ. އެހެނީ ތިޔަބައިމީހުންނަށް އީމާން ވުމަށް ގޮވައިލައްވާހިނދު، ތިޔަބައިމީހުން ކާފިރު ވަމުއެވެ.","",""],["","","","قالوا ربنا أمتنا اثنتين وأحييتنا اثنتين فاعترفنا بذنوبنا فهل إلى خروج من سبيل","އެއުރެން ދަންނަވާނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އިބަރަސްކަލާނގެ އަޅަމެން ދެފަހަރަށް މަރުގަންނަވައި، ދެފަހަރަށް ދިރުއްވައިފީމުއެވެ. ފަހެ، އަޅަމެންގެ ފާފަތަކަށް، އަޅަމެން އިޢުތިރާފް ވެއްޖައީމުއެވެ. ފަހެ، އަޅަމެންނަށް (މި އަޒާބުން) ނުކުމެވޭނޭ އެއްވެސް މަގެއް ވޭތޯއެވެ؟ (ނޯޓު: ފުރަތަމަ ފަހަރުގެ މަރަކީ، ނެތުމުގެ ތެރޭގައި އެއުރެން ވީހިނދެވެ. ދެވަނަފަހަރުގެ މަރަކީ، އަޖަލު ހަމަވެގެން ދުނިޔޭގައިވީ މަރެވެ. ފުރަތަމަ ފަހަރުގެ ދިރުއްވުމަކީ، ދުނިޔެއަށް ފޮނުއްވުމެވެ. ދެވަނަފަހަރުގެ ދިރުއްވުމަކީ، މަހުޝަރަށް ފޮނުއްވުމަށް ދިރުއްވުމެވެ.)","",""],["","","","ذلكم بأنه إذا دعي الله وحده كفرتم وإن يشرك به تؤمنوا فالحكم لله العلي الكبير","(ޖަވާބުގައި އަންގަވާނެތެވެ.) އެއީ ހަމައެކަނި ﷲއަށް އަޅުކަން ކުރުމަށް ގޮވައިލެއްވިހިނދު، ތިޔަބައިމީހުން ކާފިރު ވިކަމަށްޓަކައެވެ. އަދި އެކަލާނގެއަށް ޝަރީކުކުރާހިނދު، ތިޔަބައިމީހުން (އެކަމަށް) އީމާން ވާކަމަށްޓަކައެވެ. ފަހެ، ހުކުމްކުރެއްވުންވަނީ، އެންމެމަތިވެރި، އެންމެ ޢަޡަމަތް ތެރި ﷲއަށެވެ.","",""],["","","","هو الذي يريكم آياته وينزل لكم من السماء رزقا وما يتذكر إلا من ينيب","އެކަލާނގެއީ، ތިޔަބައިމީހުންނަށް އެކަލާނގެ (ކުޅަދުންވަންތަކަމުގެ) ހެކިތައް ދައްކަވާ، އަދި އުޑުން ތިޔަބައިމީހުންނަށްޓަކައި ރިޒްގު (އެބަހީ: އޭގެސަބަބު ކަމުގައިވާ ވާރޭ) ބާވައިލައްވާ ރަސްކަލާނގެއެވެ. އަދި ތައުބާވެ، ރުޖޫއަ ވާމީހަކު މެނުވީ (އެކަމުން) ނަސޭހަތް ލިބިއެއް ނުގަނެތެވެ.","",""],["","","","فادعوا الله مخلصين له الدين ولو كره الكافرون","ފަހެ، ތިޔަބައިމީހުން ﷲއަށް ދުއާ ކޮށް، އަޅުކަން ކުރާށެވެ! އެކަލާނގެއަށް އަޅުކަން ޚާލިސްކުރާ ޙާލު ގައެވެ. ކާފިރު ތަކުން ނުރުހުނު ކަމުގައިވިޔަސްމެއެވެ.","",""],["","","","رفيع الدرجات ذو العرش يلقي الروح من أمره على من يشاء من عباده لينذر يوم التلاق","އެކަލާނގެއީ، ދަރަޖަތައް މަތިވެރިވެގެންވާ ރަސްކަލާނގެއެވެ. ޢަރްޝުގެ ވެރިރަސްކަލާނގެއެވެ. އެކަލާނގެ އަޅުންކުރެ، އެކަލާނގެ އިރާދަކުރައްވާ އަޅަކަށް، އެކަލާނގެ އަމުރުފުޅަށް ވަހީ ފޮނުއްވަތެވެ. އެއީ އެ އަޅަކު (އެބަހީ: އެ ރަސޫލަކު) އެކަލާނގެއާ ބައްދަލުވާނޭ ދުވަހާމެދު (މީސްތަކުންނަށް) އިންޒާރުކުރެއްވުމަށްޓަކައެވެ.","",""],["","","","يوم هم بارزون لا يخفى على الله منهم شيء لمن الملك اليوم لله الواحد القهار","އެދުވަހުން އެއުރެން ފާޅުވެ ފެންނާނެތެވެ. އެއުރެންގެ އެއްވެސް ކަމެއް، ﷲއަށް ވަންހަނާވެގެނެއް ނުވާނެތެވެ. (އެދުވަހުން، ﷲ ވަހީކުރައްވާނެތެވެ.) މިއަދު ވެރިކަންއޮތީ ކާކަށްހެއްޔެވެ؟ (ޚުދު އެކަލާނގެ ޖަވާބުދެއްވާނެތެވެ.) އެއްކައުވަންތަ، ބާރުވެރިވަންތަ ﷲއަށެވެ.","",""],["","","","اليوم تجزى كل نفس بما كسبت لا ظلم اليوم إن الله سريع الحساب","މިއަދު (އެބަހީ: ގިޔާމަތް ދުވަހު) ކޮންމެ ނަފްސަކަށްމެ، އެނަފްސެއް ހޯދިކަމެއްގެ ޖަޒާދެއްވާނެތެވެ. މިއަދު އެއްވެސް ބޭއިންސާފެއް ނެތެވެ. ހަމަކަށަވަރުން ﷲއީ ހިސާބު ބެއްލެވުން އަވަސްވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وأنذرهم يوم الآزفة إذ القلوب لدى الحناجر كاظمين ما للظالمين من حميم ولا شفيع يطاع","ކައިރިވަމުންއަންނަ ދުވަހާމެދު، ކަލޭގެފާނު އެއުރެންނަށް އިންޒާރުކުރައްވާށެވެ! މޮޅިޔާއި، ހިތާމައިން ފުރިގެންވާ ޙާލު، ހިތްތައް ކަރުތެރެޔަށް އަރައިގެން އަންނަހިނދެވެ. (އެދުވަހުން) އަނިޔާވެރިންނަކަށް ރަހުމަތް ތެރިޔަކު ނުވަތަ ކިޔަމަންގަނެވޭ ޝަފާއަތް ތެރިޔަކުވެސް ނުވެއެވެ.","",""],["","","","يعلم خائنة الأعين وما تخفي الصدور","ލޮލުގެ ޚިޔާނަތް ތެރި ބެލުންތަކާއި، ހިތްތަކުގައި ފޮރުވިފައިވާ ކަންތައް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","والله يقضي بالحق والذين يدعون من دونه لا يقضون بشيء إن الله هو السميع البصير","ﷲ، ހައްގަށް ނިޔާކުރައްވަތެވެ. އަދި އެކަލާނގެ ފިޔަވައި، އެއުރެން އަޅުކަންކޮށްއުޅޭ ތަކެއްޗަށް، އެއްވެސް ނިޔާއެއް ކަނޑައެއް ނޭޅޭނެތެވެ. ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","أولم يسيروا في الأرض فينظروا كيف كان عاقبة الذين كانوا من قبلهم كانوا هم أشد منهم قوة وآثارا في الأرض فأخذهم الله بذنوبهم وما كان لهم من الله من واق","އަދި ބިމުގައި ދަތުރުފަތުރުކޮށް، އެއުރެންގެ ކުރިން އުޅުނުމީހުންގެ ނިމުންވީ، ކޮންފަދައަކުންކަން ފަހެ، އެއުރެން ނުބަލަނީހެއްޔެވެ؟ އެއުރެންނަށްވުރެ ބާރުގަދަ، އަދި ބިމުގައި އެއުރެންގެ އަސަރުތައް ވަރުގަދަ ބަޔަކު ކަމުގައި އެއުރެން (އެބަހީ: ކުރިން އުޅުނު މީހުން) ވޫއެވެ. ފަހެ، އެއުރެންގެ ފާފަތަކުގެ ސަބަބުން، ﷲ، އެއުރެން ހަލާކުކުރެއްވިއެވެ. އަދި ﷲގެ އަޒާބުން ރައްކާތެރިކޮށްދޭނޭ އެކަކުވެސް، އެއުރެންނަކަށް ނުވެއެވެ.","",""],["","","","ذلك بأنهم كانت تأتيهم رسلهم بالبينات فكفروا فأخذهم الله إنه قوي شديد العقاب","އެއީ އެއުރެންގެ ގާތަށް، އެއުރެންގެ ރަސޫލުން ފާޅުވެގެންވާ ހެކިތަކާއިގެން ވަޑައިގަތުމުން، އެއުރެން އެބޭކަލުންނަށް ކާފިރު ވީތީއެވެ. ދެން ﷲއެއުރެން ހަލާކުކުރެއްވިއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ގަދަފަދަވަންތަ، އުގޫބާތް ގަދަފަދަވެގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ولقد أرسلنا موسى بآياتنا وسلطان مبين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާއި، ފާޅުވެގެންވާ ދަލީލަކާއިގެން ތިމަންރަސްކަލާނގެ، މޫސާގެފާނު ފޮނުއްވީމެވެ.","",""],["","","","إلى فرعون وهامان وقارون فقالوا ساحر كذاب","ފިރްޢައުނާއި، ހާމާނާއި، ގާރޫނުގެ ގާތަށެވެ. ފަހެ، އެއުރެން ބުނޫއެވެ. (މިއީ) ބޮޑު ދޮގުވެރި ޖާދޫގަރެކެވެ.","",""],["","","","فلما جاءهم بالحق من عندنا قالوا اقتلوا أبناء الذين آمنوا معه واستحيوا نساءهم وما كيد الكافرين إلا في ضلال","ފަހެ، ތިމަންރަސްކަލާނގެ ހަޒުރަތުން ހައްގު ތެދުމަގާއިގެން އެއުރެންގެ ގާތަށް އެކަލޭގެފާނު ވަޑައިގަތްހިނދު، އެއުރެން ބުނޫއެވެ. އެކަލޭގެފާނުގެ އަރިހުގައި އީމާން ވެގެންތިބި މީހުންގެ ފިރިހެންދަރިން މަރާށެވެ! އަދި އެއުރެންގެ އަންހެނުން ނުމަރައި ބައިތިއްބާށެވެ! ކާފިރުންގެ މަކަރުވެރި ރޭވުންތައް، ފުރެދުމެއްގެ ތެރޭގައި މެނުވީ ނުވެއެވެ.","",""],["","","","وقال فرعون ذروني أقتل موسى وليدع ربه إني أخاف أن يبدل دينكم أو أن يظهر في الأرض الفساد","ފިރްޢައުނު ބުންޏެވެ. މޫސާގެފާނު އަވަހާރަކޮށްލުމަށް ތިޔަބައިމީހުން ތިމަން ދޫކޮށްލާށެވެ! އަދި އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް އެކަލޭގެފާނު ދުއާކުރައްވާށެވެ! ހަމަކަށަވަރުން، އެކަލޭގެފާނު ތިޔަބައިމީހުންގެ ދީން ބަދަލުކުރައްވައިފާނެކަމަށް ނުވަތަ ބިމުގައި ފަސާދަވެރިކަން ފަތުރުއްވައިފާނެކަމަށް ތިމަން ބިރުގަނެއެވެ.","",""],["","","","وقال موسى إني عذت بربي وربكم من كل متكبر لا يؤمن بيوم الحساب","މޫސާގެފާނު ވިދާޅުވިއެވެ! ހަމަކަށަވަރުން، ހިސާބު ބައްލަވާ ދުވަހަށް އީމާން ނުވާ ކޮންމެ ކިބުރުވެރިޔެއްގެ ކިބައިން ސަލާމަތްކުރެއްވުންއެދި އަހުރެންގެ ވެރި އަދި ތިޔަބައިމީހުންގެވެސް ވެރިރަސްކަލާނގެ ހަޒުރަތުން ރައްކާތެރިކަން ލިބިގަންނަމެވެ.","",""],["","","","وقال رجل مؤمن من آل فرعون يكتم إيمانه أتقتلون رجلا أن يقول ربي الله وقد جاءكم بالبينات من ربكم وإن يك كاذبا فعليه كذبه وإن يك صادقا يصبكم بعض الذي يعدكم إن الله لا يهدي من هو مسرف كذاب","ފިރްޢައުނުގެ ޚާންދާނުގެ މީހުންކުރެ އީމާން ކަން ވަންހަނާކޮށްގެންހުރި މުއުމިނު ފިރިހެނަކު ބުންޏެވެ. ތިޔަބައިމީހުން ފިރިހެނަކު (އެބަހީ: މޫސާގެފާނު) ތިޔަ ގަތުލުކުރަން އުޅެނީ ތިމަންގެ ވެރިރަސްކަލާނގެއީ، ﷲ އޭ އެކަލޭގެފާނު ވިދާޅުވާތީ ހެއްޔެވެ؟ ހަމަކަށަވަރުން، އެކަލޭގެފާނު ތިޔަބައިމީހުންގެގާތަށް ވަޑައިގަތީ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ފާޅުވެގެންވާ ހެކިތަކާއިގެންނެވެ. އަދި އެކަލޭގެފާނު ދޮގުވެރިޔެއް ކަމުގައިވާނަމަ، އެކަލޭގެފާނުގެ ދޮގުގެ ގެއްލުންހުރީ ހަމައެކަލޭގެފާނަށެވެ. އަދި އެކަލޭގެފާނީ ތެދުވެރިޔެއްކަމުގައިވާނަމަ، އެކަލޭގެފާނު ތިޔަބައިމީހުންނަށް އެ ވައުދުކުރައްވާ ކަންތަކުން ބައެއް ތިޔަބައިމީހުންނަށް ޖެހޭނެތެވެ. ހަމަކަށަވަރުން، އިސްރާފުކުރާ ބޮޑުދޮގުވެރިޔެއްކަމުގައިވާ މީހަކަށް، ﷲ ތެދުމަގެއް ނުދައްކަވާނެތެވެ.","",""],["","","","يا قوم لكم الملك اليوم ظاهرين في الأرض فمن ينصرنا من بأس الله إن جاءنا قال فرعون ما أريكم إلا ما أرى وما أهديكم إلا سبيل الرشاد","އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! މިއަދު މިސްރުގެ ބިމުގައި ވެރިކަމާއި، ބާރުލިބިފައިވަނީ ތިޔަބައިމީހުންނަށެވެ. ފަހެ، ﷲގެ އަޒާބު ތިމަންމެންނަށް އަތުވެއްޖެނަމަ، ތިމަންމެންނަށް އެހީވާނީ ކާކުހެއްޔެވެ؟ ފިރްޢައުނު ބުންޏެވެ. ތިމަންނާއަށް ފެންނައެއްޗެއް މެނުވީ، ތިޔަބައިމީހުންނަކަށް ތިމަން ނުދައްކަމެވެ. އަދި ރަނގަޅު މަގަށް މެނުވީ، ތިޔަބައިމީހުންނަކަށް މަގެއް ނުދައްކަމެވެ.","",""],["","","","وقال الذي آمن يا قوم إني أخاف عليكم مثل يوم الأحزاب","އަދި އީމާން ވިމީހާ ބުންޏެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ކާފިރު ޖަމާއަތްތަކަށް އަޒާބު އައި ދުވަސްފަދަ ދުވަހެއް، ތިޔަބައިމީހުންނަށް އަތުވެދާނެކަމަށް އަހުރެން ބިރުގަންނަމެވެ.","",""],["","","","مثل دأب قوم نوح وعاد وثمود والذين من بعدهم وما الله يريد ظلما للعباد","ނޫޙުގެފާނުގެ ގައުމުގެމީހުންނާއި، ޢާދު ބާގައިމީހުންނާއި، ޘަމޫދު ބާގައިމީހުންނާއި، އެއުރެންގެ ފަހުން އުޅުނު މީހުންގެ އާދަފަދައިންނެވެ. އަދި ﷲ، އެކަލާނގެ އަޅުންނަށް ބޭއިންސާފަކަށް އިރާދައެއް ނުކުރައްވަތެވެ.","",""],["","","","ويا قوم إني أخاف عليكم يوم التناد","އަދި އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ހަމަކަށަވަރުން، އެއްބަޔަކު އަނެއްބަޔަކަށް ގޮވާ ދުވަހާމެދު (އެބަހީ: ގިޔާމަތް ދުވަހާމެދު) ތިޔަބައިމީހުންގެ މައްޗަށް އަހުރެން ބިރުވެތިވަމެވެ.","",""],["","","","يوم تولون مدبرين ما لكم من الله من عاصم ومن يضلل الله فما له من هاد","(އެއީ) ތިޔަބައިމީހުން އެނބުރި ފުރަގަސްދީދާނެ ދުވަހެވެ. ﷲގެ އަޒާބުން ތިޔަބައިމީހުން ރައްކާތެރިކޮށްދޭނޭ އެކަކުވެސް ތިޔަބައިމީހުންނަކަށް ނުވެއެވެ. އަދި ﷲ މަގުފުރައްދަވާ މީހަކަށް ތެދުމަގުދައްކާނޭ އެކަކުވެސް ނުވެއެވެ.","",""],["","","","ولقد جاءكم يوسف من قبل بالبينات فما زلتم في شك مما جاءكم به حتى إذا هلك قلتم لن يبعث الله من بعده رسولا كذلك يضل الله من هو مسرف مرتاب","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެގާތަށް ފާޅުވެގެންވާ ހެކިތަކާއެކު، މީގެކުރިން ޔޫސުފުގެފާނު ވަޑައިގަތެވެ. ފަހެ، އެކަލޭގެފާނު އެ އެއްޗަކާއިގެން ވަޑައިގަތް އެއްޗަކާމެދު ތިޔަބައިމީހުން ޝައްކުކަމެއްގައި ދެމިތިބީމުއެވެ. އެކަލޭގެފާނު އަވަހާރަވެއްޖައުމަށް ދާނދެނެވެ. އެހިނދު ތިޔަބައިމީހުން ބުނީމުއެވެ. އެކަލޭގެފާނަށްފަހު ﷲ، ރަސޫލަކު ނުފޮނުއްވާނެތެވެ. އިސްރާފުކޮށް، ޝައްކުކުރުން ގިނަކަމުގައިވާމީހާ، ﷲ މަގުފުރައްދަވަނީ އެފަދައިންނެވެ.","",""],["","","","الذين يجادلون في آيات الله بغير سلطان أتاهم كبر مقتا عند الله وعند الذين آمنوا كذلك يطبع الله على كل قلب متكبر جبار","އެއުރެންނީ، ﷲގެ އާޔަތް ތަކާމެދުގައި އެއުރެންނަށް ލިބިފައިވާ އެއްވެސް ދަލީލަކާނުލައި ޖަދަލުކުރާ މީހުންނެވެ. ﷲގެ ހަޒުރަތު ގައްޔާއި، އީމާން ވިމީހުންގެ ގާތުގައި އެކަމަށްހުރި ނުރުހުން ބޮޑުވެގެންވެއެވެ. ކޮންމެ ކިބުރުވެރި ޖައްބާރަކުގެ ހިތުގައި ﷲ ސިއްކަގައްސަވަނީ އެފަދައިންނެވެ.","",""],["","","","وقال فرعون يا هامان ابن لي صرحا لعلي أبلغ الأسباب","ފިރްޢައުނު ބުންޏެވެ. އޭހާމާނެވެ! އަހުރެންނަށް އުސްގަނޑުވަރެއް ބިނާކޮށްދޭށެވެ! އެއީ އަހުރެންނަށް މަގުތަކެއް ފެނޭތޯއެވެ.","",""],["","","","أسباب السماوات فأطلع إلى إله موسى وإني لأظنه كاذبا وكذلك زين لفرعون سوء عمله وصد عن السبيل وما كيد فرعون إلا في تباب","އެއީ އުޑުތަކުގެ މަގުތަކެވެ. މޫސާގެފާނުގެ އިލާހު، އަހުރެންނަށް ފެނޭތޯއެވެ. އަދި ހަމަކަށަވަރުން، އަހުރެންނަށް ހީވަނީ އެކަލޭގެފާނީ ދޮގުވެރިޔެއް ކަމަށެވެ. އަދި ހަމައެފަދައިން، ފިރްޢައުނަށް އޭނާގެ ނުބައި ޢަމަލުތައް ޒީނަތްތެރިކޮށްދެއްވިއެވެ. އަދި ސީދާމަގުން އެއްކިބާކޮށްލެއްވިއެވެ. އަދި ފިރްޢައުނުގެ މަކަރުވެރި ރޭވުން، ގެއްލުމާއި، ހަލާކެއްގައި މެނުވީ ނުވެއެވެ.","",""],["","","","وقال الذي آمن يا قوم اتبعون أهدكم سبيل الرشاد","އަދި އީމާން ވިމީހާ ބުންޏެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން އަހުރެންނަށް ތަބާވާށެވެ! އޭރުން ތިޔަބައިމީހުންނަށް ރަނގަޅު މަގަށް އަހުރެން މަގު ދައްކާހުށީމެވެ.","",""],["","","","يا قوم إنما هذه الحياة الدنيا متاع وإن الآخرة هي دار القرار","އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! މިދުނިޔޭގެ ދިރިއުޅުން ވާކަންކަށަވަރީ، ވަގުތީ އަރާމެއް ކަމުގައެވެ. އަދި ހަމަކަށަވަރުން، އާޚިރަތަކީ ގަރާރުވެ ދެމިހުންނަނިވި ގޮވައްޗެވެ.","",""],["","","","من عمل سيئة فلا يجزى إلا مثلها ومن عمل صالحا من ذكر أو أنثى وهو مؤمن فأولئك يدخلون الجنة يرزقون فيها بغير حساب","ނުބައިކަމެއް ކޮށްފިމީހަކަށް، ފަހެ، އެ ނުބައިކަމާ އެއްފަދަ ޖަޒާއެއް މެނުވީ ނުލިބޭނެތެވެ. އަދި ފިރިހެނުންކުރެ، ނުވަތަ އަންހެނުންކުރެންވިޔަސް، އީމާން ވެގެންހުރެ ސާލިހު ޢަމަލު ކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެން ސުވަރުގެޔަށް ވަންނާނެތެވެ. އެތާނގައި ހިސާބެއްނެތި އެއުރެންނަށް ރިޒްގު ލިބޭނެތެވެ.","",""],["","","","ويا قوم ما لي أدعوكم إلى النجاة وتدعونني إلى النار","އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! އަހުރެން ތިޔަބައިމީހުންނަށް ސަލާމަތްވުމަށް ގޮވާއިރު، ތިޔަބައިމީހުން އަހުރެންނަށް ނަރަކަޔަށް ދިޔުމަށް ތިޔަގޮވަނީ ކީއްވެގެންހެއްޔެވެ؟","",""],["","","","تدعونني لأكفر بالله وأشرك به ما ليس لي به علم وأنا أدعوكم إلى العزيز الغفار","ތިޔަބައިމީހުން އަހުރެންނަށް ގޮވަނީ، ﷲއަށް ކާފިރު ވުމަށާއި، އަހުރެންނަށް އެނގިގެންނުވާ އެއްޗެތި އެކަލާނގެއަށް ޝަރީކުކުރުމަށެވެ. އަހުރެން ތިޔަބައިމީހުންނަށް ގޮވަނީ، ޢަޒީޒުވަންތަ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","لا جرم أنما تدعونني إليه ليس له دعوة في الدنيا ولا في الآخرة وأن مردنا إلى الله وأن المسرفين هم أصحاب النار","ޝައްކެއްނެތެވެ! ތިޔަބައިމީހުން އަހުރެން އަޅުކަންކުރުމަށް ތިޔަގޮވަނީ ދުނިޔޭގައިވެސް، އަދި އާޚިރަތް ގައިވެސް އެއަށް ގޮވުން ހައްގު ވެގެންވާ އެއްޗަކަށް ނޫނެވެ. އަދި އަހުރެމެން އެނބުރިދާހުށީ، ﷲގެ ހަޒުރަތަށެވެ. (ފުރެދުމުގައި) ހައްދުފަހަނަޅައިދާ މީހުންނީ، ހަމަ ނަރަކައިގެ އަހުލުވެރިންނެވެ.","",""],["","","","فستذكرون ما أقول لكم وأفوض أمري إلى الله إن الله بصير بالعباد","ފަހެ، އަހުރެން ތިޔަބައިމީހުންނަށް މިބުނާ އެއްޗެއް ނިކަންހުރެ ތިޔަބައިމީހުން ހަނދާންކުރާނޫއެވެ. އަދި އަހުރެންގެ ހުރިހާ ކަމެއް ﷲއަށް އަހުރެން ވަކީލުކުރަމެވެ. ހަމަކަށަވަރުން، ﷲއީ، އަޅުތަކުންގެ ކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","فوقاه الله سيئات ما مكروا وحاق بآل فرعون سوء العذاب","ފަހެ، އެއުރެންގެ ނުބައި މަކަރުވެރި ރޭވުންތަކުން ﷲ އޭނާ ސަލާމަތްކުރެއްވިއެވެ. އަދި އެންމެނުބައި އަޒާބު، ފިރްޢައުނުގެ މީހުން ވަށައިލިއެވެ.","",""],["","","","النار يعرضون عليها غدوا وعشيا ويوم تقوم الساعة أدخلوا آل فرعون أشد العذاب","އެއުރެން ހެނދުނާއި، ހަވީރު އަލިފާނަށް (އެބަހީ: ކަށްވަޅުގެ އަޒާބަށް) ހުށަހަޅުއްވާނެތެވެ. އަދި ގިޔާމަތްގެވަގުތު އަންނަދުވަހު (މަލާއިކަތުންނަށް އަންގަވާނެތެވެ.) ފިރްޢައުނުގެމީހުން އެންމެގަދަފަދަވެގެންވާ އަޒާބަށް (އެބަހީ: ނަރަކަޔަށް) ވައްދަވާށެވެ!","",""],["","","","وإذ يتحاجون في النار فيقول الضعفاء للذين استكبروا إنا كنا لكم تبعا فهل أنتم مغنون عنا نصيبا من النار","އަދި ނަރަކައިގައި އެއުރެން (އެބަހީ: ކާފިރުން) އެކަކު އަނެކަކާ އަރާރުންވާނޭހިނދު، ހަނދުމަކުރާށެވެ! ފަހެ (އެއުރެންކުރެ) ނިކަމެތިން، ބޮޑާވެގަތް ބޮޑުންނަށް ބުނާނެތެވެ. ހަމަކަށަވަރުން، ތިމަންމެންވީ ތިޔަބައިމީހުންނަށް ތަބާ ވެގެންނެވެ. ފަހެ، މި އަލިފާނުން ބައެއްނަމަވެސް، ތިމަންމެންގެ ކިބައިން ތިޔަބައިމީހުންނަށް ދުރުކޮށްދެވިދާނެ ހެއްޔެވެ؟","",""],["","","","قال الذين استكبروا إنا كل فيها إن الله قد حكم بين العباد","ބޮޑާވެގަތް ބޮޑުން ބުނާނެތެވެ. ހަމަކަށަވަރުން، އަހުރެމެން އެންމެން މިތިބީ އެއަލިފާނުގައެވެ. ހަމަކަށަވަރުން، ﷲ، އަޅުތަކުންގެ މެދުގައި، ހުކުމްކުރައްވައި ނިންމަވައިފިއެވެ.","",""],["","","","وقال الذين في النار لخزنة جهنم ادعوا ربكم يخفف عنا يوما من العذاب","އަދި ނަރަކައިގައިވާ މީހުން، ނަރަކައިގެ ބަނޑޭރިންނަށް ބުނާނެތެވެ. ތިމަންމެންގެ ކިބައިން އަޒާބުން އެއްދުވަސް ނަމަވެސް ލުއިކޮށްދެއްވާތޯ ތިޔަބޭކަލުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ދުއާ ކޮށްދެއްވާށެވެ!","",""],["","","","قالوا أولم تك تأتيكم رسلكم بالبينات قالوا بلى قالوا فادعوا وما دعاء الكافرين إلا في ضلال","އެބޭކަލުން ވިދާޅުވާނެތެވެ. ފާޅުވެގެންވާ ހެކިތަކާއިގެން ތިޔަބައިމީހުންގެ ގާތަށް، ތިޔަބައިމީހުންގެ ރަސޫލުން ވަޑައިނުގަންނަވަނީހެއްޔެވެ؟ އެއުރެން ދަންނަވާނެތެވެ. އެހެންނަކުން ނޫނެވެ. (ވަޑައިގަތެވެ.) އެބޭކަލުން ވިދާޅުވާނެތެވެ. ފަހެ، ކަލޭމެން ދުއާ ކޮށްބަލާށެވެ. ކާފިރުންގެ ދުއާ ފުރެދުމެއްގައިމެނުވީ ނުވެތެވެ.","",""],["","","","إنا لننصر رسلنا والذين آمنوا في الحياة الدنيا ويوم يقوم الأشهاد","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ރަސޫލުންނަށާއި، އީމާންވި މީހުންނަށް، ދުނިޔޭގެ ހަޔާތް ގައްޔާއި، ހެކިންތައް ތެދުވާ ދުވަހުގައި (އެބަހީ: ގިޔާމަތް ދުވަހުގައި) ނަސްރު ދެއްވާހުށީމެވެ.","",""],["","","","يوم لا ينفع الظالمين معذرتهم ولهم اللعنة ولهم سوء الدار","(އެއީ) އަނިޔާވެރިންނަށް އެއުރެންގެ އުޒުރު ދެއްކުން މަންފާއެއް ނުކުރާނޭ ދުވަހެވެ. އަދި އެއުރެންނަށް ހުރީ ލައުނަތެވެ. އަދި އެއުރެންނަށްހުރީ ނުބައިވެގެންވާ ގޮވައްޗެވެ.","",""],["","","","ولقد آتينا موسى الهدى وأورثنا بني إسرائيل الكتاب","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް ތެދުމަގު ދެއްކެވީމެވެ. އަދި އިސްރާއީލުގެދަރިންނަށް ފޮތް ވާރުތަކުރެއްވީމެވެ.","",""],["","","","هدى وذكرى لأولي الألباب","(އެއީ) ބުއްދީގެ އަހުލުވެރިންނަށް ތެދުމަގެއް ކަމުގައްޔާއި، ހަނދާންކޮށްދިނުމެއް ކަމުގައެވެ.","",""],["","","","فاصبر إن وعد الله حق واستغفر لذنبك وسبح بحمد ربك بالعشي والإبكار","ފަހެ، ކަލޭގެފާނު ކެތްކުރައްވާށެވެ! ހަމަކަށަވަރުން، ﷲގެ ވައުދު ފުޅަކީ ހައްގު ތެދެވެ. އަދި ކަލޭގެފާނުގެ ފާފަފުއްސެވުމަށް އެދިވަޑައިގަންނަވާށެވެ! އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް، ހަވީރާއި، ހެނދުނު ހަމްދާއެކު ތަސްބީހަ ވިދާޅުވާށެވެ!","",""],["","","","إن الذين يجادلون في آيات الله بغير سلطان أتاهم إن في صدورهم إلا كبر ما هم ببالغيه فاستعذ بالله إنه هو السميع البصير","ހަމަކަށަވަރުން، ﷲގެ އާޔަތް ތަކާމެދުގައި، އެއުރެންނަށް ލިބިފައވާ އެއްވެސް ދަލީލަކާނުލައި ޖަދަލުކުރާ މީހުން (ދަންނާށެވެ!) އެއުރެންގެ ހިތްތަކުގައި ބޮޑާކަމެއް މެނުވީ ނުވެތެވެ. އެއުރެންއެދޭ ކަންތަކަކަށް އެއުރެން ނުފޯރާނެއެވެ. ފަހެ، ކަލޭގެފާނު ﷲގެ ރައްކާތެރިކަމަށް އެދިވަޑައިގަންނަވާށެވެ! ހަމަކަށަވަރުން، އެކަލާނގެއީ މޮޅަށް އައްސަވާވޮޑިގެންވާ މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","لخلق السماوات والأرض أكبر من خلق الناس ولكن أكثر الناس لا يعلمون","ހަމަކަށަވަރުން، އުޑުތަކާއި، ބިން ހެއްދެވުމަކީ، މީސްތަކުން ހެއްދެވުމަށްވުރެ މާބޮޑު ކަމެކެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުންނަކަށް (އެކަމެއް) ނޭނގެތެވެ.","",""],["","","","وما يستوي الأعمى والبصير والذين آمنوا وعملوا الصالحات ولا المسيء قليلا ما تتذكرون","އަދި ލޯކަނުމީހާއާއި، ލޮލަށްފެންނަ މީހާއާ، އަދި އީމާންވެ ސާލިހު ޢަމަލުތައްކުރި މީހުންނާއި، ނުބައިކަންތައްކުރާ މީހާއާ ހަމަހަމައެއް ނުވާނެތެވެ. ތިޔަބައިމީހުން ހަނދުމަކުރަނީ ވަރަށްވެސް މަދުންނެވެ.","",""],["","","","إن الساعة لآتية لا ريب فيها ولكن أكثر الناس لا يؤمنون","ހަމަކަށަވަރުން، ގިޔާމަތްގެ ވަގުތަކީ އަންނާނޭ އެއްޗެކެވެ. އެޔާމެދަކު ޝައްކެއްނެތެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުން އީމާނެއް ނުވެތެވެ.","",""],["","","","وقال ربكم ادعوني أستجب لكم إن الذين يستكبرون عن عبادتي سيدخلون جهنم داخرين","އަދި ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ވަހީކުރެއްވިއެވެ. ތިޔަބައިމީހުން ތިމަންރަސްކަލާނގެއަށް ދުއާކުރާށެވެ! ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންގެ ދުއާ އިޖާބަކުރައްވާހުށީމެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެއަށް (ދުއާ ކޮށް) އަޅުކަން ކުރުމަށް ކިބުރުވެރިވެގަންނަ މީހުން (ދަންނާށެވެ!) ނިކަންހުރެ ނިކަމެތިވެގެންވާ ޙާލު، އެއުރެން ނަރަކަޔަށް ވަންނާނެތެވެ.","",""],["","","","الله الذي جعل لكم الليل لتسكنوا فيه والنهار مبصرا إن الله لذو فضل على الناس ولكن أكثر الناس لا يشكرون","ﷲއީ، ތިޔަބައިމީހުން، އެރޭގަނޑުގައި ހަމަހިމޭންވުމަށް، ތިޔަބައިމީހުންނަށްޓަކައި ރޭގަނޑު ލެއްވި ރަސްކަލާނގެއެވެ. އަދި (ތިޔަބައިމީހުން ދިރިއުޅުމުގެ މަސައްކަތްކުރުމަށް) ދުވާލު އަލިކޮށްދެއްވި ރަސްކަލާނގެއެވެ. ހަމަކަށަވަރުން، ﷲއީ، މީސްތަކުންގެ މައްޗަށް ފަޟްލު ވަންތަވެރި ރަސްކަލާނގެކަން ކަށަވަރެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުން ޝުކުރެއް ނުކުރެތެވެ.","",""],["","","","ذلكم الله ربكم خالق كل شيء لا إله إلا هو فأنى تؤفكون","އެއީ ﷲއެވެ. ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއެވެ. (އެކަލާނގެއީ) ހުރިހާ ތަކެއްޗެއް ހެއްދެވި ރަސްކަލާނގެއެވެ. އެކަލާނގެ މެނުވީ ހައްގު ވެގެން އަޅުކަމެއްވެވޭ އިލާހަކު ނުވެއެވެ. ފަހެ، ތިޔަބައިމީހުން (އީމާންކަމުން) އެއްކިބާވެގަންނަނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","كذلك يؤفك الذين كانوا بآيات الله يجحدون","ﷲގެ އާޔަތްތަކަށް ދެކޮޅުހަދައިއުޅުނު މީހުން (ތެދުމަގުން) އެއްކިބާވަނީ އެފަދައިންނެވެ.","",""],["","","","الله الذي جعل لكم الأرض قرارا والسماء بناء وصوركم فأحسن صوركم ورزقكم من الطيبات ذلكم الله ربكم فتبارك الله رب العالمين","ﷲއީ، ތިޔަބައިމީހުންނަށްޓަކައި، ތިޔަބައިމީހުންނަށް ހަމަޖެހިގެން ދިރިއުޅެވޭނެ ތަނެއްކަމުގައި ބިންލެއްވި ރަސްކަލާނގެއެވެ. އަދި ބިނާއެއް ކަމުގައި އުޑުލެއްވި ރަސްކަލާނގެއެވެ. އަދި ތިޔަބައިމީހުން ޞޫރަކުރައްވައި، ތިޔަބައިމީހުންގެ ޞޫރަ ރީތިކުރައްވައި، އަދި ހެޔޮތަކެތިން ތިޔަބައިމީހުންނަށް ރިޒްގު ދެއްވި ރަސްކަލާނގެއެވެ. އެއީ، ﷲއެވެ. ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއެވެ. ފަހެ، އާލަމް ތަކުގެވެރި ﷲ މަތިވެރިވެވޮޑިގެންފިއެވެ.","",""],["","","","هو الحي لا إله إلا هو فادعوه مخلصين له الدين الحمد لله رب العالمين","އެކަލާނގެއީ، ދިރިދެމިވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އެކަލާނގެ މެނުވީ އެހެން އިލާހަކު ނުވެއެވެ. ފަހެ، ތިޔަބައިމީހުން އެކަލާނގެއަށް އަޅުކަން ޚާލިސްކުރާ ޙާލު، އެކަލާނގެއަށް ދުއާ ކޮށް އަޅުކަން ކުރާށެވެ! ހަމްދު ހުރީ އާލަމް ތަކުގެވެރި ﷲއަށެވެ.","",""],["","","","قل إني نهيت أن أعبد الذين تدعون من دون الله لما جاءني البينات من ربي وأمرت أن أسلم لرب العالمين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ބަޔާންވެގެންވާ ހެކިތައް، ތިމަންކަލޭގެފާނަށް އައިހިނދު، ތިޔަބައިމީހުން ﷲ ފިޔަވައި އަޅުކަންކުރާ ތަކެއްޗަށް އަޅުކަންކުރުން، ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނަށް ނަހީކުރެއްވިއެވެ. އަދި އާލަމްތަކުގެ ވެރިރަސްކަލާނގެއަށް ކިޔަމަންގަތުމަށް ތިމަންކަލޭގެފާނަށް އަމުރުކުރެއްވިއެވެ.","",""],["","","","هو الذي خلقكم من تراب ثم من نطفة ثم من علقة ثم يخرجكم طفلا ثم لتبلغوا أشدكم ثم لتكونوا شيوخا ومنكم من يتوفى من قبل ولتبلغوا أجلا مسمى ولعلكم تعقلون","އެކަލާނގެއީ، ތިޔަބައިމީހުން ވެލިން ހެއްދެވި ރަސްކަލާނގެއެވެ. ދެން މަނިތިއްކަކުންނެވެ. ދެން ގަނޑުލޭކޮޅަކުންނެވެ. ދެން އެކަލާނގެ، ތިޔަބައިމީހުން ޅަކުދިންގެ ގޮތުގައި (މައިމީހާގެ ބަނޑުން) ނެރުއްވަތެވެ. ދެން ތިޔަބައިމީހުން ބޮޑުވެ ފުރާފުރިހަމަވުމާ ހަމަޔަށް ފޯރުމަށްޓަކައެވެ. ދެން ތިޔަބައިމީހުން މުސްކުޅިންނަށް ވުމަށްޓަކައެވެ. އަދި އޭގެކުރިން މަރުވާ މީހުން ތިޔަބައިމީހުންގެ ތެރެއިންވެއެވެ. އަދި ތިޔަބައިމީހުން ކަނޑައެޅިގެންވާ މުއްދަތަކަށް ފޯރުމަށްޓަކައެވެ. އަދި ތިޔަބައިމީހުން ވިސްނުމަށްޓަކައެވެ.","",""],["","","","هو الذي يحيي ويميت فإذا قضى أمرا فإنما يقول له كن فيكون","އެކަލާނގެއީ، ދިރުއްވައި، އަދި މަރުގަންނަވާ ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެ ކަމަކަށް ނިޔާކުރައްވައިފިނަމަ ފަހެ، އެކަމަކަށް ވަހީކުރައްވާކަން ކަށަވަރީ، [ވާށޭ] އެވެ. ދެން އެކަމެއް ވެދެތެވެ.","",""],["","","","ألم تر إلى الذين يجادلون في آيات الله أنى يصرفون","ﷲގެ އާޔަތް ތަކާމެދު ޖަދަލުކުރާ މީހުން، ތިބާ ނުދެކެމުހެއްޔެވެ؟ އެއުރެން (ހައްގު މަގުން) އެއްކިބާވަނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","الذين كذبوا بالكتاب وبما أرسلنا به رسلنا فسوف يعلمون","އެއުރެންނީ، މިފޮތާއި (އެބަހީ: ގުރްއާނާއި) ތިމަންރަސްކަލާނގެ ރަސޫލުން އެފޮތްތަކާއިގެން ފޮނުއްވި ފޮތްތައް ދޮގުކުރި މީހުންނެވެ. ފަހެ، (އެކަމުގެ ނަތީޖާ) ނިކަންހުރެ އެއުރެންނަށް އެނގޭނެތެވެ.","",""],["","","","إذ الأغلال في أعناقهم والسلاسل يسحبون","އެއުރެންގެ ކަނދުރާތަކުގައި، ކަސްތޮޅުއެޅި ހިލިހިލާޖެހި، އެއުރެން ދަމައި، ގެންދަވާހިނދުގައެވެ.","",""],["","","","في الحميم ثم في النار يسجرون","ކެކިކެކިހުރި ހޫނުފެނުގެ ތެރެޔަށެވެ. ދެން ނަރަކައިގެ އަލިފާނުގެ ތެރޭގައި އެއުރެން އަންދަވާނެތެވެ.","",""],["","","","ثم قيل لهم أين ما كنتم تشركون","ދެން އެއުރެންނަށް އަންގަވާނެތެވެ. ﷲ ފިޔަވައި ތިޔަބައިމީހުން ޝަރީކު ކޮށް އުޅުނު ތަކެތި ކޮބައިހެއްޔެވެ؟ އެއުރެން ބުނާނެތެވެ. އެތަކެތި ތިމަންމެންގެ ކިބައިން ބީވެގެން ހިނގައްޖެއެވެ. އަދި ކިއެއްތަ! މީގެކުރިން ތިމަންމެން އެއްވެސް އެއްޗަކަށް އަޅުކަންކޮށް ގޮވައިނަހަދަމުއެވެ. ﷲ، ކާފިރު ވިމީހުން މަގުފުރައްދަވަނީ އެފަދައިންނެވެ.","",""],["","","","من دون الله قالوا ضلوا عنا بل لم نكن ندعو من قبل شيئا كذلك يضل الله الكافرين","ދެން އެއުރެންނަށް އަންގަވާނެތެވެ. ﷲ ފިޔަވައި ތިޔަބައިމީހުން ޝަރީކު ކޮށް އުޅުނު ތަކެތި ކޮބައިހެއްޔެވެ؟ އެއުރެން ބުނާނެތެވެ. އެތަކެތި ތިމަންމެންގެ ކިބައިން ބީވެގެން ހިނގައްޖެއެވެ. އަދި ކިއެއްތަ! މީގެކުރިން ތިމަންމެން އެއްވެސް އެއްޗަކަށް އަޅުކަންކޮށް ގޮވައިނަހަދަމުއެވެ. ﷲ، ކާފިރު ވިމީހުން މަގުފުރައްދަވަނީ އެފަދައިންނެވެ.","",""],["","","","ذلكم بما كنتم تفرحون في الأرض بغير الحق وبما كنتم تمرحون","އެއީ ހައްގަކާ ނުލައި ބިމުގައި ތިޔަބައިމީހުން (އުރެދުންތަކަށް) އުފާކޮށް އުޅުނުކަމުގެ ސަބަބުންނެވެ. އަދި ބޮޑާވެ، މަޖާކޮށް އުޅުނުކަމުގެ ސަބަބުންނެވެ.","",""],["","","","ادخلوا أبواب جهنم خالدين فيها فبئس مثوى المتكبرين","ތިޔަބައިމީހުން ނަރަކައިގެ ދޮރުތަކުން ވަންނާށެވެ! އެތާނގައި ދެމިތިބެނިވި ގޮތުގައެވެ. ފަހެ (އެއީ) ކިބުރުވެރިން ތިބުމަށް ހާދަހާ ނުބައިވެގެންވާ ތަނެކެވެ.","",""],["","","","فاصبر إن وعد الله حق فإما نرينك بعض الذي نعدهم أو نتوفينك فإلينا يرجعون","ފަހެ، ކަލޭގެފާނު ކެތްކުރައްވާށެވެ! ހަމަކަށަވަރުން، ﷲގެ ވައުދު ފުޅަކީ ހައްގު ތެދެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ވައުދުކުރައްވާ ބައެއްކަންތައް، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ދެއްކެވިޔަސް ނުވަތަ (އޭގެކުރިން) ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު މަރުގެންނެވިޔަސް، ފަހެ، އެއުރެން ރުޖޫއަ ވާހުށީ، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","ولقد أرسلنا رسلا من قبلك منهم من قصصنا عليك ومنهم من لم نقصص عليك وما كان لرسول أن يأتي بآية إلا بإذن الله فإذا جاء أمر الله قضي بالحق وخسر هنالك المبطلون","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ކުރިން ތިމަންރަސްކަލާނގެ ރަސޫލުން ފޮނުއްވީމެވެ. އެ ރަސޫލުންގެ ވާހަކަ ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނަށް ކިޔައިދެއްވާފައިވާ ރަސޫލުން، އޭގެތެރެއިންވެއެވެ. އަދި އެ ރަސޫލުންގެ ވާހަކަ، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ކިޔައިދެއްވާފައިނުވާ ރަސޫލުންވެސް އޭގެތެރެއިންވެއެވެ. އަދި އެއްވެސް ރަސޫލަކަށް ﷲގެ އިޒުނަ ފުޅާލައިގެން މެނުވީ، އެއްވެސް މުއުޖިޒާއެއް ގެންނެވުމެއް ނުވެއެވެ. ފަހެ، ﷲގެ އަމުރުފުޅު އަންނަހިނދު، ހައްގަށް ނިޔާކުރައްވާހުށްޓެވެ. އަދި އެތާނގައި ބާތިލުގެ އަހުލުވެރިން ގެއްލި ހަލާކުވެދާހުށްޓެވެ.","",""],["","","","الله الذي جعل لكم الأنعام لتركبوا منها ومنها تأكلون","ﷲއީ، ތިޔަބައިމީހުންނަށްޓަކައި ނަޢަމް ސޫފި ލެއްވި ރަސްކަލާނގެއެވެ. (އެއީ) ތިޔަބައިމީހުން އެއިން (ބައެއް ތަކެއްޗަށް) ސަވާރުވެ އަދި އެއިން ބައެއް ތަކެތި ކެއުމަށްޓަކައެވެ.","",""],["","","","ولكم فيها منافع ولتبلغوا عليها حاجة في صدوركم وعليها وعلى الفلك تحملون","އަދި އެތަކެތީގައި ތިޔަބައިމީހުންނަށް މަންފާތަކެއްވެއެވެ. އަދި ތިޔަބައިމީހުންގެ ހިތްތަކުގައިވާ ބޭނުންތަކަށް އެތަކެތީގެ މަތީގައި (ދަތުރުކޮށް) ތިޔަބައިމީހުން ފޯރުމަށްޓަކައެވެ. އަދި އެތަކެތީގެ މަތީގައްޔާއި، އުޅަނދުތަކުގައި ތިޔަބައިމީހުން (އެއްތަނުން، އަނެއްތަނަށް) އުފުއްލެއެވެ.","",""],["","","","ويريكم آياته فأي آيات الله تنكرون","އަދި އެކަލާނގެ ތިޔަބައިމީހުންނަށް، އެކަލާނގެ އާޔަތްތައް ދައްކަވަތެވެ. ފަހެ، ﷲގެ އާޔަތްތަކުގެ ތެރެއިން ތިޔަބައިމީހުން އިންކާރުކުރަނީ ކޮންއާޔަތަކަށް ހެއްޔެވެ؟","",""],["","","","أفلم يسيروا في الأرض فينظروا كيف كان عاقبة الذين من قبلهم كانوا أكثر منهم وأشد قوة وآثارا في الأرض فما أغنى عنهم ما كانوا يكسبون","ފަހެ، އެއުރެން ބިމުގައި ދަތުރުފަތުރުކޮށް، އެއުރެންގެ ކުރިން އުޅުނުމީހުންގެ ނިމުންވީ ކޮންފަދައަކުންކަން، ފަހެ، އެއުރެން ނުބަލަނީހެއްޔެވެ؟ އެއުރެންނަށްވުރެ އަދަދު ގިނަ، އަދި ބާރުގަދަ، އަދި ބިމުގައި އެއުރެންގެ އަޘަރުތައް ވަރުގަދަ ބަޔަކުކަމުގައި އެއުރެން (އެބަހީ، ކުރިންއުޅުނުމީހުން) ވޫއެވެ. ފަހެ، އެއުރެން ހޯދައިއުޅުނު ތަކެތި އެއުރެންނަކަށް އެއްވެސްކަމެއް ފުއްދައެއް ނުދިނެވެ.","",""],["","","","فلما جاءتهم رسلهم بالبينات فرحوا بما عندهم من العلم وحاق بهم ما كانوا به يستهزئون","ފަހެ، އެއުރެންގެ ރަސޫލުން ފާޅުވެގެންވާ ހެކިތަކާއިގެން އެއުރެންގެގާތަށް ވަޑައިގަތްހިނދު، އެއުރެންގެ ގާތުގައިވާ (ދުނިޔޭގެ) އިލްމަށްޓަކައި، އެއުރެން އުފާކުރޫއެވެ. އަދި އެއުރެން ފުރައްސާރަކޮށްއުޅުނު ކަންތައްއައިސް އެއުރެން ވަށައިލިއެވެ.","",""],["","","","فلما رأوا بأسنا قالوا آمنا بالله وحده وكفرنا بما كنا به مشركين","ފަހެ، ތިމަންރަސްކަލާނގެ އަޒާބު، އެއުރެންނަށް ފެނުނުހިނދު އެއުރެން ބުނޫއެވެ. ހަމައެކަނި، ﷲއަށް ތިމަންމެން އީމާން ވެއްޖައީމުއެވެ. އަދި ތިމަންމެން ޝަރީކު ކޮށް އުޅުނު ތަކެއްޗަށް ކާފިރު ވެއްޖައީމުއެވެ.","",""],["","","","فلم يك ينفعهم إيمانهم لما رأوا بأسنا سنت الله التي قد خلت في عباده وخسر هنالك الكافرون","ފަހެ، ތިމަންރަސްކަލާނގެ އަޒާބެއުރެންނަށް ފެނުނުހިނދު، އެއުރެންވީ އީމާނުން އެއުރެންނަށް މަންފާއެއް ކުރާނެކަމުގައި ނުވެތެވެ. (އެއީ) ﷲ، އެކަލާނގެ އަޅުތަކުންނާމެދު ކަންހިންގަވާފައިވާގޮތެވެ. އަދި އެތާނގައި ކާފިރު ވިމީހުން ގެއްލި ހަލާކުވެއްޖައޫއެވެ.","",""],["","","","بسم الله الرحمن الرحيم حم","ح م (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","تنزيل من الرحمن الرحيم","މިއީ ރަޙްމާންވަންތަ ރަޙީމްވަންތަ ރަސްކަލާނގެ ހަޒުރަތުން ބާވައިލެއްވި ފޮތެކެވެ.","",""],["","","","كتاب فصلت آياته قرآنا عربيا لقوم يعلمون","އެފޮތުގެ އާޔަތްތައް ތަފްޞީލު ކޮށްދެއްވާފައިވާ ފޮތެކެވެ. އަރަބި ބަހުންވާ ގުރްއާނެއްގެ ގޮތުގައެވެ. (އެއީ އެކަން) ދަންނަ ބަޔަކަށްޓަކައެވެ.","",""],["","","","بشيرا ونذيرا فأعرض أكثرهم فهم لا يسمعون","އުފާވެރިކަމުގެ ޚަބަރު ދޭ، އަދި ބިރުވެރިކަމުގެ ޚަބަރު ދޭ ފޮތެއްކަމުގައެވެ. ފަހެ، އެއުރެންކުރެ ގިނަމީހުން ފުރަގަސްދީ އެނބުރިގަތޫއެވެ. ފަހެ، އެއުރެން އަޑެއް ނާހަތެވެ.","",""],["","","","وقالوا قلوبنا في أكنة مما تدعونا إليه وفي آذاننا وقر ومن بيننا وبينك حجاب فاعمل إننا عاملون","އަދި އެއުރެން ބުނޫއެވެ. ތިމަންމެންގެ ހިތްތައްވަނީ، ކަލޭގެފާނު ތިޔަ ގޮވައިލައްވާ އެއްޗަކަށް ބަންދުކަމެއްގައެވެ. އަދި ތިމަންމެންގެ ކަންފަތްތަކުގައި ބީރުކަމެއްވެއެވެ. އަދި ތިމަންމެންނާއި، ކަލޭގެފާނާ ދެމެދުގައި ފަރުދާއެއްވެއެވެ. ފަހެ (ކަލޭގެފާނުގެ ގޮތުގައި) ކަލޭގެފާނު މަސައްކަތްކުރައްވާށެވެ! ހަމަކަށަވަރުން، ތިމަންމެންވެސް (ތިމަންމެންގެ ގޮތުގައި) މަސައްކަތް ކުރާނޫއެވެ.","",""],["","","","قل إنما أنا بشر مثلكم يوحى إلي أنما إلهكم إله واحد فاستقيموا إليه واستغفروه وويل للمشركين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނު ވާކަންކަށަވަރީ، ތިޔަބައިމީހުންކަހަލަ އާދަމުގެދަރިޔަކު ކަމުގައެވެ. ތިމަންކަލޭގެފާނަށް ވަހީ އިއްވަވަނީ، ތިޔަބައިމީހުންގެ އިލާހަކީ، އެއް އިލާހެއްކަމުގައެވެ. ފަހެ، ތިޔަބައިމީހުން އެކަލާނގެއަށް ސީދާވާށެވެ! އަދި ފާފަފުއްސެވުންއެދި، އެކަލާނގެއަށް ދަންނަވާށެވެ! އަދި ޝަރީކުކުރާ މީހުންނަށް ހަލާކުހުށްޓެވެ.","",""],["","","","الذين لا يؤتون الزكاة وهم بالآخرة هم كافرون","އެއުރެންނީ ޒަކާތް ނުދޭ މީހުންނެވެ. އަދި އެއުރެންނީ (ހަމަ) އާޚިރަތް ދުވަހަށް ކާފިރުވާ މީހުންނެވެ.","",""],["","","","إن الذين آمنوا وعملوا الصالحات لهم أجر غير ممنون","ހަމަކަށަވަރުން، އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަމީހުންނަށް ކެނޑިގެންނުދާނޭ ދަރުމަހުށްޓެވެ.","",""],["","","","قل أئنكم لتكفرون بالذي خلق الأرض في يومين وتجعلون له أندادا ذلك رب العالمين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ދެދުވަހުގެ ތެރޭގައި، ބިން ހެއްދެވި ރަސްކަލާނގެއަށް ތިޔަބައިމީހުން ކާފިރުވެ، އަދި އެކަލާނގެއަށް ތިޔަބައިމީހުން ޝަރީކުންތަކެއް ލަނީހެއްޔެވެ؟ އެކަލާނގެއީ، އާލަމްތަކުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["","","","وجعل فيها رواسي من فوقها وبارك فيها وقدر فيها أقواتها في أربعة أيام سواء للسائلين","އަދި އެކަލާނގެ، ފުރިހަމަ ހަތަރު ދުވަހުގެ ތެރޭގައި، އެ ބިމުގެ މަތީގައި އުފުލިފައިވާ، ހަރުލައިހުންނަ ފަރުބަދަތައް ލައްވައި، އަދި އެ ބިމުގައި ބަރަކާތްލައްވައި، އަދި އެ ބިމުގައި ވާހާތަކެތީގެ ރިޒްގު މިންވަރުކުރެއްވިއެވެ. (އެއީ) ސުވާލުކުރާ މީހުންނަށްޓަކައެވެ.","",""],["","","","ثم استوى إلى السماء وهي دخان فقال لها وللأرض ائتيا طوعا أو كرها قالتا أتينا طائعين","ދެން ދުމެއްގެ ސިފައިގައި އުޑުވަނިކޮށް، އުޑުހައްދަވައި، ފުރިހަމަކުރެއްވުމަށް އެކަލާނގެ އިރާދަކުރެއްވިއެވެ. ފަހެ، އެކަލާނގެ އެ އުޑަށާއި، ބިމަށް ވަހީކުރެއްވިއެވެ. ރުހުމުގައި، ނުވަތަ ނުރުހުމުގައިވިޔަސް (ފުރާފުރިހަމަވެގެން) އަންނާށެވެ! އެ އުޑާއި ބިން ދެންނެވިއެވެ. ތިމަންމެން ރުހުމުގައި އަތުވެއްޖައީމުއެވެ.","",""],["","","","فقضاهن سبع سماوات في يومين وأوحى في كل سماء أمرها وزينا السماء الدنيا بمصابيح وحفظا ذلك تقدير العزيز العليم","ފަހެ، ދެދުވަހުގެ ތެރޭގައި އެކަލާނގެ ހަތް އުޑު ހެއްދެވިއެވެ. އަދި ކޮންމެ އުޑަކަށް، އެ އުޑެއްގެ ކަންތައް (ތަދްބީރުކުރައްވައި) އެންގެވިއެވެ. އަދި ބައްތިތަކަކުން ތިމަންރަސްކަލާނގެ އެންމެ ކައިރި އުޑު ޒީނަތްތެރިކުރައްވައި، އަދި އެ އުޑު ރައްކާތެރި ކުރެއްވީމެވެ. އެއީ ޢަޒީޒުވަންތަ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެ މިންވަރު ކުރައްވާފައިވާ ގޮތެވެ.","",""],["","","","فإن أعرضوا فقل أنذرتكم صاعقة مثل صاعقة عاد وثمود","ފަހެ، އެއުރެން ފުރަގަސްދީ އެނބުރިގެންފިނަމަ، ފަހެ، ކަލޭގެފާނު (އެއުރެންނަށް) ވިދާޅުވާށެވެ! ޢާދު ބާގައިމީހުންނާއި ޘަމޫދު ބާގައިމީހުންނަށް އައި ހޮނުގުގުރީގެ އަޒާބު ފަދަ އަޒާބެއް، ތިޔަބައިމީހުންނަށް އަތުވެދާނެކަމަށް އިންޒާރުކުރައްވަމެވެ.","",""],["","","","إذ جاءتهم الرسل من بين أيديهم ومن خلفهم ألا تعبدوا إلا الله قالوا لو شاء ربنا لأنزل ملائكة فإنا بما أرسلتم به كافرون","އެއުރެންގެގާތަށް، އެއުރެންގެ ކުރިމަތިންނާއި، އެއުރެންގެ ފަހަތުން ރަސޫލުން ވަޑައިގެން ﷲއަށް މެނުވީ އަޅުކަން ނުކުރުމަށް އެންގެވިހިނދު، އެއުރެން ބުނޫއެވެ. ތިމަންމެންގެ ވެރިރަސްކަލާނގެ (ރަސޫލުން ފޮނުއްވެވުމަށް) އިރާދަކުރެއްވިނަމަ، ފޮނުއްވީހީ މަލާއިކަތުންނެވެ. ފަހެ، ހަމަކަށަވަރުން، ތިޔަބޭކަލުން އެކަންތަކާއިގެން ފޮނުއްވެވި ކަންތަކަށް، ތިމަންމެން ކާފިރު ވަމުއެވެ.","",""],["","","","فأما عاد فاستكبروا في الأرض بغير الحق وقالوا من أشد منا قوة أولم يروا أن الله الذي خلقهم هو أشد منهم قوة وكانوا بآياتنا يجحدون","ފަހެ، ޢާދު ބާގައިމީހުން ދަންނާށެވެ! އެއުރެން ހައްގަކާ ނުލައި ބިމުގައި ބޮޑާވެގަތޫއެވެ. އަދި އެއުރެން ބުނޫއެވެ. ތިމަންމެންނަށްވުރެ ބާރުގަދައީ ކާކުހެއްޔެވެ؟ އެއުރެން ހެއްދެވި ﷲ، އެއުރެންނަށްވުރެ ބާރުގަދަކަން އެއުރެންނަށް ނޭނގެނީހެއްޔެވެ؟ އަދި ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް ދެކޮޅުހަދާ ބަޔަކުކަމުގައި އެއުރެންވޫއެވެ.","",""],["","","","فأرسلنا عليهم ريحا صرصرا في أيام نحسات لنذيقهم عذاب الخزي في الحياة الدنيا ولعذاب الآخرة أخزى وهم لا ينصرون","ފަހެ، ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް ސުންޕާދުވަސްތަކެއްގައި، ގަދަ އަޑާއި، ގަދަ ފިނީގެ ވަޔެއް ފޮނުއްވީމެވެ. ދުނިޔޭގެ ހަޔާތުގައި ނިކަމެތިކަމުގެ އަޒާބުގެ ރަހަ، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްކެވުމަށްޓަކައެވެ. އަދި ހަމަކަށަވަރުން، އާޚިރަތްގެ އަޒާބުގެ ނިކަމެތިކަން މާބޮޑެވެ. އަދި އެއުރެންނަކަށް ނަސްރެއް ނުލިބޭނެތެވެ.","",""],["","","","وأما ثمود فهديناهم فاستحبوا العمى على الهدى فأخذتهم صاعقة العذاب الهون بما كانوا يكسبون","އަދި ޘަމޫދު ބާގައިމީހުން ދަންނާށެވެ! ފަހެ، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ތެދުމަގު ދެއްކެވީމެވެ. ފަހެ، އެއުރެން ތެދުމަގު ލިބުމުގެ ބަދަލުގައި، ކަނުކަން (އެބަހީ: މަގު ފުރެދުން) އިޚްތިޔާރުކުރޫއެވެ. އެއުރެން ހޯދައިއުޅުނު ޢަމަލުތަކުގެ ސަބަބުން، އިހާނަތްތެރި އަޒާބުގެ ހޮނުގުގުރި އެއުރެންގައި ހިފިއެވެ.","",""],["","","","ونجينا الذين آمنوا وكانوا يتقون","އަދި އީމާންވެ، ތަގުވާވެރިވާކަމުގައިވިމީހުން، ތިމަންރަސްކަލާނގެ ސަލާމަތް ކުރެއްވީމެވެ.","",""],["","","","ويوم يحشر أعداء الله إلى النار فهم يوزعون","އަދި ﷲގެ އަދުއްވުން އެންމެން އެކުގައި ނަރަކަޔަށް އެއްކުރައްވާދުވަސް ހަނދުމަކުރާށެވެ!","",""],["","","","حتى إذا ما جاءوها شهد عليهم سمعهم وأبصارهم وجلودهم بما كانوا يعملون","އެ ނަރަކަޔަށް އެއުރެން ޙާޒިރުު ވެއްޖައުމަށް ދާނދެނެވެ. އެހިނދު އެއުރެންގެ ކަންފަތާއި، އެއުރެންގެ ލޯތަކާއި، އެއުރެންގެ ހަންތައް، އެއުރެން ކޮށްއުޅުނު ޢަމަލުތަކަށް ހެކިދޭނެތެވެ.","",""],["","","","وقالوا لجلودهم لم شهدتم علينا قالوا أنطقنا الله الذي أنطق كل شيء وهو خلقكم أول مرة وإليه ترجعون","އަދި އެއުރެންގެ ހަންތަކަށް އެއުރެން ބުނާނެތެވެ. ކަލޭމެން ތިމަންމެންގެ މައްޗަށް ހެކިދިނީ ކީއްވެގެންހެއްޔެވެ؟ އެތަކެތި ބުނާނެތެވެ. ކޮންމެ އެއްޗަކަށްވެސް ބަސްމޮށުންދެއްވި ﷲ، ތިމަންމެންނަށް ބަސްމޮށުންދެއްވީއެވެ. އަދި އެކަލާނގެއީ، ފުރަތަމަ ފަހަރަށް ތިޔަބައިމީހުން ހެއްދެވި ރަސްކަލާނގެއެވެ. އަދި ތިޔަބައިމީހުން އެނބުރި ރުޖޫއަކުރައްވާހުށީ އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","وما كنتم تستترون أن يشهد عليكم سمعكم ولا أبصاركم ولا جلودكم ولكن ظننتم أن الله لا يعلم كثيرا مما تعملون","ތިޔަބައިމީހުންގެ ކަންފަތާއި، ތިޔަބައިމީހުންގެ ލޯތަކާއި، ތިޔަބައިމީހުންގެ ހަންތައް، ތިޔަބައިމީހުންގެ މައްޗަށް ހެކިދީފާނެކަމަށް ތިޔަބައިމީހުން (އެއްވެސްކަމެއް) ވަންހަނާކޮށެއް ނޫޅެމުއެވެ. އެހެނެއްކަމަކު ތިޔަބައިމީހުންހީކުރީ، ތިޔަބައިމީހުން ކޮށްއުޅޭ ޢަމަލު ތަކުން ގިނަކަންތައް ﷲ ދެނެވޮޑިގެންނުވާނޭ ކަމަށެވެ.","",""],["","","","وذلكم ظنكم الذي ظننتم بربكم أرداكم فأصبحتم من الخاسرين","އެއީ ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއާމެދު ތިޔަބައިމީހުން ހީކުރި ހީކުރުމެވެ. އެ ހީކުރުން ތިޔަބައިމީހުން ހަލާކުކޮށްލައިފިއެވެ. އަދި ގެއްލެނިވެގެންވާ މީހުންގެ ތެރެއިން ތިޔަބައިމީހުން ވެއްޖައީމުއެވެ.","",""],["","","","فإن يصبروا فالنار مثوى لهم وإن يستعتبوا فما هم من المعتبين","ފަހެ، އެއުރެން ކެތްކުރާނަމަވެސް، އެއުރެން ތިބެނިވިތަނަކީ، ނަރަކަޔެވެ. އެއުރެން އުޒުރު ދެއްކުމަށް އެދޭނަމަ، ފަހެ އުޒުރު ގަބޫލުކުރައްވާނެ މީހުންގެ ތެރެޔަކުން އެއުރެން ނުވެތެވެ.","",""],["","","","وقيضنا لهم قرناء فزينوا لهم ما بين أيديهم وما خلفهم وحق عليهم القول في أمم قد خلت من قبلهم من الجن والإنس إنهم كانوا خاسرين","އަދި ތިމަންރަސްކަލާނގެ އެއުރެންނަށް އެކުވެރިންތަކެއް ލެއްވީމެވެ. ފަހެ، އެ އެކުވެރިން އެއުރެންނަށް، އެއުރެންގެ ކުރިމަތީގައިވާ ކަންތަކާއި، އެއުރެންގެ ފަހަތުގައިވާ ކަންތައް ޒީނަތްތެރިކޮށްދިނެވެ. އަދި އެއުރެންގެކުރިން އިސްވެ ގޮސްފައިވާ (ފުރެދުނު) ޖިންނީންނާއި، އިންސީންގެ އުއްމަތްތަކުގެ ތެރޭގައި އެއުރެންގެ މައްޗަށް އަޒާބުގެ ބަސްފުޅު ހައްގު ވެއްޖެއެވެ. ހަމަކަށަވަރުން، އެއުރެންވީ ގެއްލެނިވިގެންވާ މީހުން ކަމުގައެވެ.","",""],["","","","وقال الذين كفروا لا تسمعوا لهذا القرآن والغوا فيه لعلكم تغلبون","ކާފިރު ވިމީހުން ބުނޫއެވެ. ތިޔަބައިމީހުން މި ގުރްއާން އަޑުނާހާށެވެ! (އަދި ގުރްއާން ކިޔެވޭހިނދު) ތިޔަބައިމީހުން އަޑުގަދަކުރާށެވެ! އެއީ ތިޔަބައިމީހުންނަށް ގަދަވެގަނެވޭތޯއެވެ!","",""],["","","","فلنذيقن الذين كفروا عذابا شديدا ولنجزينهم أسوأ الذي كانوا يعملون","ފަހެ، ހަމަކަށަވަރުން، ކާފިރު ވިމީހުންނަށް ތިމަންރަސްކަލާނގެ ގަދަވެގެންވާ އަޒާބުގެ ރަހަ ދައްކަވާހުށީމެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެން ކޮށްއުޅުނު ނުބައި ޢަމަލުތަކަށް ޖަޒާ ދެއްވާހުށީމެވެ.","",""],["","","","ذلك جزاء أعداء الله النار لهم فيها دار الخلد جزاء بما كانوا بآياتنا يجحدون","އެއީ ﷲގެ އަދާވަތް ތެރިންގެ ޖަޒާއެވެ. (އެއީ) ނަރަކަޔެވެ. އެތާނގައި އެއުރެންނަށް ދެމިތިބެނިވި ގޮވައްޗެއްވެއެވެ. ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް އެއުރެން ދެކޮޅުހަދައި އުޅުނުކަމުގެ ޖަޒާއެއްގެގޮތުގައެވެ.","",""],["","","","وقال الذين كفروا ربنا أرنا اللذين أضلانا من الجن والإنس نجعلهما تحت أقدامنا ليكونا من الأسفلين","ކާފިރު ވިމީހުން ބުނާނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ޖިންނީންނާއި، އިންސީންގެ ތެރެއިން އަޅަމެން މަގުފުރެއްދި ދެބައިމީހުން އަޅަމެންނަށް ދައްކަވާނދޭވެ! އެ ދެބައިމީހުން އަޅަމެންގެ ފައިތިލަތަކުގެ ދަށަށް ލާހުށީމެވެ. (އެއީ) އެ ދެބައިމީހުން (އަޒާބުގެ) އެންމެއަޑީގައި ވުމަށްޓަކައެވެ.","",""],["","","","إن الذين قالوا ربنا الله ثم استقاموا تتنزل عليهم الملائكة ألا تخافوا ولا تحزنوا وأبشروا بالجنة التي كنتم توعدون","ހަމަކަށަވަރުން، ތިމަންމެންގެ ވެރިރަސްކަލާނގެއީ ﷲ އޭ ބުނެ، ދެން ސީދާމަގުގައި ދެމިތިބިމީހުން (ދަންނާށެވެ!) އެއުރެންގެ މައްޗަށް މަލާއިކަތުން ފައިބައިވަޑައިގަންނަވާނެތެވެ. ވިދާޅުވަމުންނެވެ. ތިޔަބައިމީހުން ބިރުނުގަންނާށެވެ! އަދި ހިތާމަނުކުރާށެވެ! އަދި ތިޔަބައިމީހުންނަށް ވައުދުކުރައްވާކަމުގައިވާ ސުވަރުގޭގެ އުފާވެރިކަމުގެ ޚަބަރު ލިބިގަންނާށެވެ!","",""],["","","","نحن أولياؤكم في الحياة الدنيا وفي الآخرة ولكم فيها ما تشتهي أنفسكم ولكم فيها ما تدعون","ތިމަންބޭކަލުންނީ ދުނިޔޭގެ ހަޔާތް ގައްޔާއި، އާޚިރަތުގައި ތިޔަބައިމީހުންގެ އެހީތެރިންނެވެ. ތިޔަބައިމީހުންގެ ނަފްސުތައް އެދޭހާކަމެއް އެދުވަހުން، ތިޔަބައިމީހުންނަށްޓަކައިވެއެވެ. އަދި (އުފަލާއި، އަރާމުގެތެރެއިން) ތިޔަބައިމީހުން ދަންނަވާހާކަމެއް ތިޔަބައިމީހުންނަށްވެއެވެ.","",""],["","","","نزلا من غفور رحيم","ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ކަލެއްގެ މެހުމާންދާރީއެއްގެ ގޮތުގައެވެ.","",""],["","","","ومن أحسن قولا ممن دعا إلى الله وعمل صالحا وقال إنني من المسلمين","ﷲގެ ހަޒުރަތަށް (އައުމަށް) ގޮވާލައި، އަދި ސާލިހު ޢަމަލު ކޮށް، އަދި ހަމަކަށަވަރުން، ތިމަންނާވަނީ (ﷲއަށް) ކިޔަމަންވާމީހުންގެ ތެރެއިންނޭ ބުނާމީހަކަށްވުރެ ރަނގަޅު ބަސްބުނާ މީހަކީ ކާކުހެއްޔެވެ؟","",""],["","","","ولا تستوي الحسنة ولا السيئة ادفع بالتي هي أحسن فإذا الذي بينك وبينه عداوة كأنه ولي حميم","ރަނގަޅު ކަންތަކާއި، ނުބައިކަންތައް ހަމަހަމަވެގެނެއް ނުވެތެވެ. އެންމެހެޔޮ، ރިވެތިގޮތުން ތިބާ (ނުބައިކަންތައް) ދުރުކުރާށެވެ. ފަހެ، އެހާރުން ތިބާއާ އޭނާއާ ދެމެދުގައި އަދާވަތް ތެރިކަމެއްވާ މީހާ، ގާތް ރަހުމަތް ތެރިޔަކު ފަދައިން ވެދާނެތެވެ.","",""],["","","","وما يلقاها إلا الذين صبروا وما يلقاها إلا ذو حظ عظيم","އަދި ކެތްތެރިވި މީހުންނަށްމެނުވީ، އެ މާތްސިފަ ލިބިއެއް ނުގަނެވޭނެތެވެ. އަދި ބޮޑުވެގެންވާ ނަސީބުވެރިޔަކަށްމެނުވީ، އެ މާތްސިފަ ލިބިއެއް ނުގަނެވޭނެތެވެ.","",""],["","","","وإما ينزغنك من الشيطان نزغ فاستعذ بالله إنه هو السميع العليم","އަދި ހަމަކަށަވަރުން، ޝައިތާނާގެ ފަރާތުން ވަސްވާސްތެރިކަމެއްއައިސް ކަލޭގެފާނުގެ ހިތްޕުޅަށް ވަންނަނަމަ، ﷲގެ ރައްކާތެރިކަމަށް އެދިވަޑައިގަންނަވާށެވެ! ހަމަކަށަވަރުން، އެކަލާނގެއީ، މޮޅަށްއައްސަވާވޮޑިގެންވާ، މޮޅަށްދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ومن آياته الليل والنهار والشمس والقمر لا تسجدوا للشمس ولا للقمر واسجدوا لله الذي خلقهن إن كنتم إياه تعبدون","ރޭގަނޑާއި ދުވާލާއި، އިރާއި، ހަނދަކީ، އެކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެކިތަކުގެ ތެރެއިން ވާތަކެއްޗެވެ. ތިޔަބައިމީހުން އިރަށާއި، ހަނދަށް ސަޖިދަ ނުކުރާށެވެ! އަދި އެތަކެތި ހެއްދެވި ﷲއަށް ސަޖިދަކުރާށެވެ! (އެއީ) ހަމައެކަނި އެކަލާނގެއަށް ތިޔަބައިމީހުން އަޅުކަންކުރާ ކަމުގައިވާނަމައެވެ.","",""],["","","","فإن استكبروا فالذين عند ربك يسبحون له بالليل والنهار وهم لا يسأمون","ފަހެ، އެއުރެން (ﷲއަށް ސަޖިދަކުރުމަށް) ބޮޑާވެގެންފިނަމަ، ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތު ގައިވާ މަލާއިކަތުން އެކަލާނގެއަށް ރެޔާއިދުވާލު ތަސްބީހަ ދަންނަވަތެވެ. އަދި އެބޭކަލުން އެކަމަކަށް ފޫހިފުޅެއްނުވެތެވެ.","",""],["","","","ومن آياته أنك ترى الأرض خاشعة فإذا أنزلنا عليها الماء اهتزت وربت إن الذي أحياها لمحيي الموتى إنه على كل شيء قدير","ގަހެއްނެތި ހިކިފައިވާ ބިން، ތިބާ ދެކޭނޫއެވެ. ފަހެ، އެ ބިމުގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ވާރޭ ވެއްސަވައިފިހިނދު، އެބިމުގެ ގަސްތަކުގެ ޙަރަކާތް ފެށި، ގަސްތައް އިތުރުވެއެވެ. އެއީ އެކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެކިތަކުގެ ތެރެއިންވާ ކަމެކެވެ. ހަމަކަށަވަރުން، އެ ބިންގަނޑު ދިރުއްވި ރަސްކަލާނގެއީ، މަރުވެފައިވާ ތަކެތި ދިރުއްވާ ރަސްކަލާނގެއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ކޮންމެކަމެއްގެ މައްޗަށްމެ ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","إن الذين يلحدون في آياتنا لا يخفون علينا أفمن يلقى في النار خير أم من يأتي آمنا يوم القيامة اعملوا ما شئتم إنه بما تعملون بصير","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާމެދުގައި ދެކޮޅުހަދައި، އެއްކިބާވާމީހުން ތިމަންރަސްކަލާނގެއަށް ވަންހަނާވެގެންނެއްނުވެތެވެ. ފަހެ، ހެޔޮކަންބޮޑީ ނަރަކަޔަށް އެއްލައިލެވޭ މީހާހެއްޔެވެ؟ ނުވަތަ ގިޔާމަތް ދުވަހު އަމާންކަމާއެކުގައި އަންނަމީހާ ހެއްޔެވެ؟ ތިޔަބައިމީހުން އެދޭކަމެއްކުރާށެވެ! ހަމަކަށަވަރުން، އެކަލާނގެއީ، ތިޔަބައިމީހުން ކުރާކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","إن الذين كفروا بالذكر لما جاءهم وإنه لكتاب عزيز","ހަމަކަށަވަރުން، އެއުރެންގެގާތަށް ގުރްއާން އައިހިނދު، އެ ގުރްއާނަށް ކާފިރު ވިމީހުންނަށް (ގަދަވެގެންވާ އަޒާބު ހުށްޓެވެ.) ހަމަކަށަވަރުން، އެއީ ބާރުގަދަ ފޮތެއްކަން ކަށަވަރެވެ.","",""],["","","","لا يأتيه الباطل من بين يديه ولا من خلفه تنزيل من حكيم حميد","އެ ފޮތުގެ ކުރިމައްޗަކުންވެސް، އަދި އޭގެފަހަތަކުންވެސް އެފޮތަކަށް ބާތިލުކަމެއް ނާންނާނެތެވެ. (އެއީ) ހަމްދު ލިބިވޮޑިގެންވާ، ޙަކީމް ވަންތަރަސްކަލާނގެ ހަޒުރަތުން ބާވައިލެއްވި ފޮތެކެވެ.","",""],["","","","ما يقال لك إلا ما قد قيل للرسل من قبلك إن ربك لذو مغفرة وذو عقاب أليم","ކަލޭގެފާނުގެ ކުރިންފޮނުއްވި ރަސޫލުންނަށްވެސް ދެންނެވުނު ބަސްތަކެއްމެނުވީ، ކަލޭގެފާނަކަށް ނުދެންނެވެތެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ފާފަފުއްސެވުމުގެ ވެރި، އަދި ވޭންދެނިވި އަޒާބު ދެއްވުމުގެ ވެރިރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","ولو جعلناه قرآنا أعجميا لقالوا لولا فصلت آياته أأعجمي وعربي قل هو للذين آمنوا هدى وشفاء والذين لا يؤمنون في آذانهم وقر وهو عليهم عمى أولئك ينادون من مكان بعيد","ތިމަންރަސްކަލާނގެ އަރަބި ނޫން ބަހަކުން ގުރްއާނެއް ބާވައިލެއްވިނަމަ، އެއުރެން ބުނީހެވެ. (އަރަބި ބަހުން) އެ ފޮތުގެ އާޔަތްތައް ތަފްޞީލުކުރައްވާފައިވާނަމަ، ކިހާރަނގަޅު ހެއްޔެވެ؟ އެފޮތް އަރަބި ނޫން ބަހަކުން އޮވެފައި، އެ ފޮތް ބާވައިލެއްވީ، އަރަބީއަކަށް ހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެ ފޮތަކީ، އީމާންވި މީހުންނަށްވާ ތެދުމަގެކެވެ. އަދި ޝިފާއެއްވެސްމެއެވެ. އަދި އީމާން ނުވާމީހުންގެ ކަންފަތްތަކުގައި ބީރުކަމެއްވެއެވެ. އަދި އެ ފޮތަކީ، އެއުރެންގެ މައްޗަށްވާ ކަނުކަމެކެވެ. އެއުރެން ދުރުތަނަކުން ގޮވައިލެވޭ ބަޔެއްފަދައެވެ.","",""],["","","","ولقد آتينا موسى الكتاب فاختلف فيه ولولا كلمة سبقت من ربك لقضي بينهم وإنهم لفي شك منه مريب","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ މޫސާގެފާނަށް ފޮތް ދެއްވީމެވެ. ފަހެ، އެ ފޮތާމެދު ޚިލާފު ވެވުނެވެ. ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އިސްވެދިޔަ ބަސްފުޅެއް ނުވާނަމަ، އެއުރެންގެ މެދުގައި ނިޔާކުރެއްވީސްކަން ކަށަވަރެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެންވަނީ އެކަމާމެދު ވަސްވާސްތެރިކަމުން ފުރިގެންވާ، ޝައްކެއްގައިކަން ކަށަވަރެވެ.","",""],["","","","من عمل صالحا فلنفسه ومن أساء فعليها وما ربك بظلام للعبيد","ސާލިހު ޢަމަލެއްކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެކަމުގެ ދަރުމަހުރީ އެމީހާގެ އަމިއްލަ ނަފްސަށެވެ. އަދި ނުބައި ޢަމަލެއްކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެކަމުގެ ހަލާކުހުރީ، ހަމަ އެ ނަފްސުގެ މައްޗަށެވެ. އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، އަޅުތަކުންނަށް އަނިޔާވެރިވެވޮޑިގެންވާ ކަލަކުކަމުގައެއް ނުވެއެވެ.","",""],["","","","إليه يرد علم الساعة وما تخرج من ثمرات من أكمامها وما تحمل من أنثى ولا تضع إلا بعلمه ويوم يناديهم أين شركائي قالوا آذناك ما منا من شهيد","ގިޔާމަތް ދުވަސް އައުމުގެ ވަގުތު ދެނެވޮޑިގަތުންވަނީ ހަމައެކަނި އެކަލާނގެއަށެވެ. އެކަލާނގެ ދެނެވޮޑިގަތުމާ އެކުގައިމެނުވީ، އެއްވެސް މޭވާއެއް އޭގެ ބޮށިގަނޑަކުން ނުނިކުންނާނެތެވެ. އަދި އަންހެނަކު މާބަނޑެއް ނުވާނެތެވެ. އަދި ނުވެސް ވިހާނެތެވެ. އަދި ތިމަންރަސްކަލާނގެއަށް ޝަރީކުކުރިމީހުން ކޮބައިހޭ އެކަލާނގެ ގޮވައިލައްވައި ވަހީކުރައްވާ ދުވަހު، އެއުރެން ބުނާނެތެވެ. (އިބަރަސްކަލާނގެއަށް ޝަރީކަކުވާކަމަށް) ހެކިވާ ހަމައެކަކުވެސް، ތިމަންމެންގެ ތެރޭގައި ނުވާކަމަށް އިބަރަސްކަލާނގެއަށް ތިމަންމެން މިދެންނެވީއެވެ.","",""],["","","","وضل عنهم ما كانوا يدعون من قبل وظنوا ما لهم من محيص","އަދި މީގެކުރިން އެއުރެން ދުއާ ކޮށް، އަޅުކަންކޮށްއުޅުނު ތަކެތި އެއުރެންގެކިބައިން ގެއްލިހިނގައްޖެއެވެ. އަދި (އަޒާބުން) އެއުރެން ފިލަންދާނެތަނެއް ނެތްކަން، އެއުރެންނަށް ޔަގީން ވެއްޖެއެވެ.","",""],["","","","لا يسأم الإنسان من دعاء الخير وإن مسه الشر فيئوس قنوط","ހެޔޮކަންތަކަށް ދުއާކުރުމަކަށް އިންސާނާ ފޫއްސެއް ނުވާނެތެވެ. އަދި އޭނާއަށް ނުބައިކަމެއް ޖެހިއްޖެނަމަ، ފަހެ، އުންމީދުކެނޑި، ހިތްމަރުވެފައިވާ މީހަކަށް އޭނާ ވެދެތެވެ.","",""],["","","","ولئن أذقناه رحمة منا من بعد ضراء مسته ليقولن هذا لي وما أظن الساعة قائمة ولئن رجعت إلى ربي إن لي عنده للحسنى فلننبئن الذين كفروا بما عملوا ولنذيقنهم من عذاب غليظ","އަދި ހަމަކަށަވަރުން، އެ އިންސާނާއަށް ދަތި ޙާލެއް ޖެހިއްޖައުމަށްފަހު، ތިމަންރަސްކަލާނގެ ހަޒުރަތުން ރަހުމަތެއްގެ ރަހަ އޭނާއަށް ދައްކަވައިފިނަމަ، މިއީ ތިމަންނާއަށްހުރި ތަކެއްޗޭ ބުނާނެކަން ކަށަވަރެވެ. އަދި ގިޔާމަތް ވާނެކަމަކަށް ތިމަންނާ ހީއެއްނުކުރަމެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ތިމަން ރުޖޫއަކުރެއްވިއަސް ހަމަކަށަވަރުން އެކަލާނގެ ހަޒުރަތުގައި ތިމަންނައަށްހުރީ ހެޔޮކަމެވެ. ފަހެ، ހަމަކަށަވަރުން، ކާފިރު ވިމީހުންނަށް ތިމަންރަސްކަލާނގެ އެއުރެންކުރި ޢަމަލުތަކުގެ ޚަބަރު އަންގަވާހުށީމެވެ. އަދި ހަމަކަށަވަރުން، ގަދަފަދަވެގެންވާ އަޒާބަކުން އެއުރެންނަށް ތިމަންރަސްކަލާނގެ އަޒާބުގެ ރަހަ ދައްކަވާހުށީމެވެ.","",""],["","","","وإذا أنعمنا على الإنسان أعرض ونأى بجانبه وإذا مسه الشر فذو دعاء عريض","އަދި އިންސާނާއަށް ތިމަންރަސްކަލާނގެ ނިއުމަތް ދެއްވައިފިނަމަ، އަނެއްފަރާތަށް އެނބުރި ބޮޑާވެގަނެތެވެ. އަދި އޭނާއަށް، ނުބައިކަމެއް ޖެހިއްޖެނަމަ، ފަހެ، ދުއާކުރުން ގިނަމީހަކަށް އޭނާ ވެދެތެވެ.","",""],["","","","قل أرأيتم إن كان من عند الله ثم كفرتم به من أضل ممن هو في شقاق بعيد","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ނިކަންބުނެބަލާށެވެ! ﷲގެ ހަޒުރަތު ންއައި އެއްޗެއްކަމަށް އެ (ގުރްއާން) ވެފައި، ދެން ތިޔަބައިމީހުން އެއަށް ކާފިރު ވެއްޖެނަމަ (ތިޔަބައިމީހުންގެ ޙާލު ވާނީ ކޮންފަދައަކުން ހެއްޔެވެ؟ ހައްގާ) ދުރުވެގެންވާ، ދެކޮޅުވެރިކަމެއްގައިވާ މީހަކަށްވުރެ ފުރެދުންބޮޑީ ކާކުހެއްޔެވެ؟","",""],["","","","سنريهم آياتنا في الآفاق وفي أنفسهم حتى يتبين لهم أنه الحق أولم يكف بربك أنه على كل شيء شهيد","އުދަރެސްތަކުގައްޔާއި، އެއުރެންގެ އަމިއްލަ ނަފްސު ތަކުގައިވާ، ތިމަންރަސްކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެކިތައް، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ނިކަންހުރެ ދައްކަވާހުށީމެވެ. އެއީ ހައްގު ތެދުކަން އެއުރެންނަށް ބަޔާންވެ އެނގިއްޖައުމަށް ދާނދެނެވެ. ކަލޭގެފާނުންގެ ވެރިރަސްކަލާނގެއީ ކޮންމެކަމެއްގެ މައްޗަށް ހެކިވެވޮޑިގެންވާ ކަލަކުކަމުގައި ނުފުދޭހެއްޔެވެ؟","",""],["","","","ألا إنهم في مرية من لقاء ربهم ألا إنه بكل شيء محيط","ދަންނާށެވެ! ހަމަކަށަވަރުން، އެއުރެންގެ ވެރިރަސްކަލާނގެއާ ބައްދަލުވާނެ ކަމާމެދު އެއުރެންވަނީ ޝައްކުކަމެއްގައެވެ. ދަންނާށެވެ! ހަމަކަށަވަރުން، އެކަލާނގެއީ، ކޮންމެކަމެއް ފުރިހަމަޔަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم حم","ح م ع س ق (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","عسق","ح م ع س ق (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","كذلك يوحي إليك وإلى الذين من قبلك الله العزيز الحكيم","ކަލޭގެފާނަށާއި ކަލޭގެފާނުގެ ކުރީގެ ރަސޫލުންނަށް، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ﷲ ވަހީކުރައްވަނީ އެފަދައިންނެވެ.","",""],["","","","له ما في السماوات وما في الأرض وهو العلي العظيم","އުޑުތަކުގައިވާހާ ތަކެއްޗާއި، ބިމުގައިވާހާ ތަކެތި މިލްކުވެގެންވަނީ އެކަލާނގެއަށެވެ. އަދި އެކަލާނގެއީ، އެންމެމަތިވެރި، އެންމެމާތް ރަސްކަލާނގެއެވެ.","",""],["","","","تكاد السماوات يتفطرن من فوقهن والملائكة يسبحون بحمد ربهم ويستغفرون لمن في الأرض ألا إن الله هو الغفور الرحيم","(ﷲގެ ކީރިތިވަންތަކަމުން) އުޑުތައް އެތަކެތީގެމަތިން ފަޅަފަޅައިގެންދިއުމާ ގާތްވެއެވެ. އަދި މަލާއިކަތުން، އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ހަމްދާއެކު ތަސްބީހަ ދަންނަވަތެވެ. އަދި ބިމުގައިވާ މީހުންނަށް ފާފަފުއްސެވުންއެދި، ދުއާކުރައްވަތެވެ. ދަންނާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","والذين اتخذوا من دونه أولياء الله حفيظ عليهم وما أنت عليهم بوكيل","އެކަލާނގެ ފިޔަވައި އެހީތެރިންތަކެއް ހިފިމީހުން (ދަންނާށެވެ!) ﷲ، އެއުރެންގެ މައްޗަށް މޮޅަށް ބައްލަވާވޮޑިގެންވެއެވެ. އަދި އެއުރެންގެ ކަންތައްތައް ޙަވާލުކުރައްވާފައިވާ ވަކީލަކު ކަމުގައި ކަލޭގެފާނު ނުވަމުއެވެ.","",""],["","","","وكذلك أوحينا إليك قرآنا عربيا لتنذر أم القرى ومن حولها وتنذر يوم الجمع لا ريب فيه فريق في الجنة وفريق في السعير","އަދި ހަމައެފަދައިން އަރަބި ބަހުންވާ ގުރްއާނެއް، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ވަހީކުރެއްވީމެވެ. (އެއީ) މައިރަށުގެ (އެބަހީ: މައްކާގެ) އަހުލުވެރިންނާއި، އެތާނގެ ވަށައިގެންވާ މީހުންނަށް ކަލޭގެފާނު އިންޒާރުކުރެއްވުމަށްޓަކައެވެ. އަދި (ޚަލްގު ތަކުން) އެއްކުރައްވާ ދުވަހާމެދު އިންޒާރުކުރެއްވުމަށްޓަކައެވެ. އެދުވަހާމެދަކު ޝައްކެއްނެތެވެ. (އެދުވަހުން) އެއްބަޔަކުވާހުށީ ސުވަރުގޭގައެވެ. އަދި އަނެއްބަޔަކު ވާހުށީ ނަރަކައިގައެވެ.","",""],["","","","ولو شاء الله لجعلهم أمة واحدة ولكن يدخل من يشاء في رحمته والظالمون ما لهم من ولي ولا نصير","އަދި ﷲ އިރާދަކުރެއްވިނަމަ، އެއުރެން އެއް އުއްމަތެއްކަމުގައި ލައްވައިފީހެވެ. އެހެނެއްކަމަކު، އެކަލާނގެ އިރާދަކުރައްވާމީހަކު، އެކަލާނގެ ރަހުމަތްގެ ތެރެޔަށް ވައްދަވަތެވެ. އަދި އަނިޔާވެރިންނަށް (އެދުވަހުން) އެހީތެރިޔެއްވެސް، އަދި ނަސްރުވެރިޔެއްވެސް ނުވެތެވެ.","",""],["","","","أم اتخذوا من دونه أولياء فالله هو الولي وهو يحيي الموتى وهو على كل شيء قدير","ނުވަތަ އެއުރެން ﷲ ފިޔަވައި އެހީތެރިންތަކެއް ހޯދީހެއްޔެވެ؟ ފަހެ، އެހީތެރިޔަކީ ހަމަ ﷲއެވެ. އަދި އެކަލާނގެ، މަރުވެފައިވާ ތަކެތި ދިރުއްވަތެވެ. އަދި އެކަލާނގެއީ، ކޮންމެކަމެއްގެމައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وما اختلفتم فيه من شيء فحكمه إلى الله ذلكم الله ربي عليه توكلت وإليه أنيب","އަދި ތިޔަބައިމީހުން އެކަމަކާމެދުގައި ޚިލާފުވާ ކޮންމެ ކަމެއްގެ ހުކުމްކުރެއްވުންވަނީ، ﷲއަށެވެ. އެއީ ﷲއެވެ. ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއެވެ. އެކަލާނގެއަށް ތިމަންކަލޭގެފާނު ވަކީލުކުރައްވައިފީމެވެ. އަދި ތައުބާ ވަނީ ހަމައެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","فاطر السماوات والأرض جعل لكم من أنفسكم أزواجا ومن الأنعام أزواجا يذرؤكم فيه ليس كمثله شيء وهو السميع البصير","އެކަލާނގެއީ، އިސްވެދިޔަ މިސާލަކާނުލައި އުޑުތަކާއި، ބިންހެއްދެވި ރަސްކަލާނގެއެވެ. އެކަލާނގެ ތިޔަބައިމީހުންނަށްޓަކައި ތިޔަބައިމީހުންގެ ތެރެއިން އަނބިން ލެއްވިއެވެ. އަދި އެކަލާނގެ ނަޢަމް ސޫފީގެ ތެރެއިން ދެ ޖިންސުގެ ތަކެތި ލެއްވިއެވެ. އެކަލާނގެ އެގޮތުން ތިޔަބައިމީހުން ގިނަކުރައްވަތެވެ. އެކަލާނގެއާ އެއްފަދަ އެއްވެސް އެއްޗެއް ނުވެތެވެ. އަދި އެކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","له مقاليد السماوات والأرض يبسط الرزق لمن يشاء ويقدر إنه بكل شيء عليم","އުޑުތަކާއި، ބިމުގެ ތަޅުދަނޑިތައް މިލްކުވެގެންވަނީ އެކަލާނގެއަށެވެ. އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ރިޒްގު ތަނަވަސްކޮށްދެއްވަތެވެ. އަދި (އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ރިޒްގު) ދަތިކުރައްވަތެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ކޮންމެކަމެއްމެ މޮޅަށްދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","شرع لكم من الدين ما وصى به نوحا والذي أوحينا إليك وما وصينا به إبراهيم وموسى وعيسى أن أقيموا الدين ولا تتفرقوا فيه كبر على المشركين ما تدعوهم إليه الله يجتبي إليه من يشاء ويهدي إليه من ينيب","ތިޔަބައިމީހުންނަށްޓަކައި، އެކަލާނގެ ޝަރުއުކުރެއްވި ދީނަކީ، އެކަލާނގެ ނޫޙުގެފާނަށް ވަސިއްޔަތްކުރެއްވި ދީނެވެ. އަދި ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ވަހީކުރެއްވި ދީނެވެ. އަދި އިބްރާހީމްގެފާނަށާއި، މޫސާގެފާނަށާއި، ޢީސާގެފާނަށް ވަސިއްޔަތްކުރެއްވި ދީނެވެ. (އެ ވަސިއްޔަތަކީ) ތިޔަބައިމީހުން ދީން ގާއިމުކުރާށެވެ! އަދި އޭގައި ތިޔަބައިމީހުން ބައިބައިނުވާހުށިކަމެވެ! ތިޔަބައިމީހުން އެކަމަކަށް ތިޔަގޮވައިލާ ކަންތައް، މުޝްރިކުންގެ މައްޗަށް ބޮޑުކަމަކަށްވިއެވެ. ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ އަޅަކު ޚިޔާރުކުރައްވަތެވެ. އަދި އެކަލާނގެއަށް ތައުބާވެ، ރުޖޫއަ ވާމީހާއަށް ތެދުމަގު ދައްކަވަތެވެ.","",""],["","","","وما تفرقوا إلا من بعد ما جاءهم العلم بغيا بينهم ولولا كلمة سبقت من ربك إلى أجل مسمى لقضي بينهم وإن الذين أورثوا الكتاب من بعدهم لفي شك منه مريب","އަދި ބައިބައިވުމަކީ ނުބައިކަމެއްކަން، އެއުރެންނަށް އެނގުނުފަހުން މެނުވީ، އެއުރެން ބައިބައިވެ ޚިލާފެއް ނުވެތެވެ. އެއީ އެއުރެންގެ މެދުގައިވާ ދެކޮޅުވެރިކަމާއި، ހަސަދަވެރިކަމުންނެވެ. އަދި ކަނޑައެޅިގެންވާ ވަގުތަކަށް ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން (އަޒާބު ދެއްވުމުގެ) ބަސްފުޅެއް އިސްވެގޮސްފައިނުވާނަމަ، އެއުރެންގެ މެދުގައި ނިޔާކަނޑައެޅުއްވީސްކަން ކަށަވަރެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެންގެފަހުން، ފޮތްވާރުތަވީމީހުންވަނީ، އެފޮތާމެދު ވަސްވާސްތެރިކަމުން ފުރިގެންވާ ޝައްކެއްގައިކަން ކަށަވަރެވެ.","",""],["","","","فلذلك فادع واستقم كما أمرت ولا تتبع أهواءهم وقل آمنت بما أنزل الله من كتاب وأمرت لأعدل بينكم الله ربنا وربكم لنا أعمالنا ولكم أعمالكم لا حجة بيننا وبينكم الله يجمع بيننا وإليه المصير","އެކަމަށްޓަކައި (ބައިބައިވުމުން ދުރުހެލިވެ، އެންމެން އެކަތިގަނޑަކަށްވުމަށް) ފަހެ، ކަލޭގެފާނު ގޮވައިލައްވާށެވެ! އަދި ކަލޭގެފާނަށް އަމުރުކުރެއްވި ފަދައިން ސީދާވެވަޑައިގަންނަވާށެވެ! އެއުރެންއެދޭ ބާތިލު ގޮތްތަކަށް ކަލޭގެފާނު ތަބާ ވެވަޑައިނުގަންނަވާށެވެ! އަދި ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲ ބާވައިލެއްވި ކޮންމެ ފޮތަކަށް އަހުރެން އީމާން ވެއްޖައީމެވެ. އަދި އަހުރެންނަށް އަމުރުކުރައްވާފައިވަނީ، ތިޔަބައިމީހުންގެ މެދުގައި ޢަދުލުވެރިގޮތުގައި ކަންތައްކުރުމަށެވެ. ﷲއީ، އަޅަމެންގެ ވެރިރަސްކަލާނގެއެވެ. އަދި ތިޔަބައިމީހުންގެވެސް ވެރިރަސްކަލާނގެއެވެ. ތިމަންމެންނަށް ތިމަންމެންގެ ޢަމަލު ތަކެވެ. އަދި ތިޔަބައިމީހުންނަށް ތިޔަބައިމީހުންގެ ޢަމަލު ތަކެވެ. ތިޔަބައިމީހުންނާ އަހުރެމެންނާދެމެދު ޖަދަލުކޮށް ޒުވާބުކުރުމެއްނެތެވެ. ﷲ، އަހުރެމެން އެންމެން (ގިޔާމަތް ދުވަހުގައި) އެއްކުރައްވާނެތެވެ. އަދި އެނބުރިދިއުންވަނީ، އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","والذين يحاجون في الله من بعد ما استجيب له حجتهم داحضة عند ربهم وعليهم غضب ولهم عذاب شديد","މީސްތަކުން އެކަލާނގެ ދީން ގަބޫލު ކޮށް އިޖާބަދިނުމަށްފަހު، ﷲގެ ދީނާމެދު، ޖަދަލުކުރާ މީހުންނީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި، އެއުރެންގެ ހުއްޖަތް ބާތިލު ވެގެންވާ ބަޔެކެވެ. އަދި އެއުރެންގެ މައްޗަށް ކޯފާހުށްޓެވެ. އަދި އެއުރެންނަށްޓަކައި (އާޚިރަތުގައި) ވަނީ ގަދަފަދަ އަޒާބެވެ.","",""],["","","","الله الذي أنزل الكتاب بالحق والميزان وما يدريك لعل الساعة قريب","ހައްގު ގޮތުގައި ފޮތާއި، ޢަދުލު އިންޞާފު ބާވައިލެއްވީ ﷲއެވެ. ގިޔާމަތް ވުމުގެ ވަގުތު ގާތްވެގެންވާކަން، ކަލޭގެފާނަށް އަންގައިދެނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","يستعجل بها الذين لا يؤمنون بها والذين آمنوا مشفقون منها ويعلمون أنها الحق ألا إن الذين يمارون في الساعة لفي ضلال بعيد","އެދުވަހަށް (އެބަހީ: ގިޔާމަތް ދުވަހަށް) އީމާން ނުވާމީހުން އެދުވަސް އަވަހަށް އައުމަށް އެދޭނެތެވެ. އަދި އީމާން ވިމީހުން އެދުވަހަށް ބިރުވެތިވާނެތެވެ. އެދުވަހަކީ، ހަމަކަށަވަރުން، ހައްގު ގޮތުގައި އަންނާނޭ ދުވަހެއްކަން، އެއުރެން ދަނެތެވެ. ދަންނާށެވެ! ހަމަކަށަވަރުން، ގިޔާމަތް ދުވަހާމެދު ޖަދަލުކުރާމީހުންވަނީ، ދުރުވެގެންވާ މަގުފުރެދުމެއްގައިކަން ކަށަވަރެވެ.","",""],["","","","الله لطيف بعباده يرزق من يشاء وهو القوي العزيز","ﷲއީ، އެކަލާނގެ އަޅުތަކުންނަށް އޯގާވަންތަކަންބޮޑު ރަސްކަލާނގެއެވެ. އެކަލާނގެ އިރާދަކުރައްވާ އަޅަކަށް ރިޒްގު ދެއްވަތެވެ. އަދި އެކަލާނގެއީ، ބާރުވެރިވަންތަ، ޢަޒީޒުވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","من كان يريد حرث الآخرة نزد له في حرثه ومن كان يريد حرث الدنيا نؤته منها وما له في الآخرة من نصيب","އާޚިރަތްގެ ސަވާބަށްއެދި މަސައްކަތްކުރާ މީހާއަށް އޭނާގެ ސަވާބު، ތިމަންރަސްކަލާނގެ އިތުރުކުރައްވާ ހުށީމެވެ. އަދި ދުނިޔޭގެ މަންފާތަކަށް އެދޭމީހާއަށް، ތިމަންރަސްކަލާނގެ އެއިން ދެއްވާހުށީމެވެ. އަދި އާޚިރަތުގައި އޭނާޔަށް (ސަވާބުގެ) އެއްވެސް ނަސީބެއްނެތެވެ.","",""],["","","","أم لهم شركاء شرعوا لهم من الدين ما لم يأذن به الله ولولا كلمة الفصل لقضي بينهم وإن الظالمين لهم عذاب أليم","ނުވަތަ ﷲ، އިޒުނަ ދެއްވާފައިނުވާ ދީނެއް، އެއުރެންނަށް، ޝަރުއު ކޮށް ކަނޑައަޅައިދިން ޝަރީކުންތަކެއް އެއުރެންނަށް ވޭހެއްޔެވެ؟ ޖަޒާދެއްވުން ކަނޑައެޅިގެންވާ ދުވަހަށް ލަސްކުރެއްވުމުގެ ކަލިމަ ފުޅުނުވާނަމަ، އެއުރެންގެމެދުގައި ނިޔާ ކަނޑައެޅުއްވީސްކަން ކަށަވަރެވެ. އަދި ހަމަކަށަވަރުން، އަނިޔާވެރިންނަށް ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["","","","ترى الظالمين مشفقين مما كسبوا وهو واقع بهم والذين آمنوا وعملوا الصالحات في روضات الجنات لهم ما يشاءون عند ربهم ذلك هو الفضل الكبير","އަނިޔާވެރިން، އެއުރެން ހޯދި ނުބައިކަންތަކަށް ލިބޭ އަޒާބަށް ބިރުވެތިވާތީ (އެދުވަހުން) ތިބާ ދެކޭނޫއެވެ. އެ އަޒާބު އައިސް އެއުރެންނަށް ޖެހޭހުށްޓެވެ. އަދި އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަމީހުން ވާހުށީ، ސުވަރުގޭގެ ބަގީޗާތަކުގައެވެ. އެއުރެން އެދޭކަންތައް، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި، އެއުރެންނަށްވެއެވެ. ބޮޑުވެގެންވާ ފަޟްލު ވަންތަކަމަކީ ހަމައެއީއެވެ.","",""],["","","","ذلك الذي يبشر الله عباده الذين آمنوا وعملوا الصالحات قل لا أسألكم عليه أجرا إلا المودة في القربى ومن يقترف حسنة نزد له فيها حسنا إن الله غفور شكور","އެއީ އީމާންވެ، ސާލިހު ޢަމަލުތައް ކުޅަ، އެކަލާނގެ އަޅުތަކުންނަށް ﷲ އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާ ކަންތަކެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަމުގެ މައްޗަށް (އެބަހީ: ތިމަންކަލޭގެފާނުގެ ރަސޫލު ކަން އިއްވެވުމުގެ މައްޗަކަށް) ތިމަންކަލޭގެފާނު، ތިޔަބައިމީހުންގެ ކިބަޔަކުން އެއްވެސް އުޖޫރަޔަކަށް އެދިވަޑައެއް ނުގަންނަވަމެވެ. ގާތްތިމާގެކަމުގެ ލޯބިމެނުވީއެވެ. އަދި ހެޔޮކަމެއްކުރާ މީހާއަށް ތިމަންރަސްކަލާނގެ އެކަމުގައި ހެޔޮކަން އިތުރުކޮށްދެއްވާހުށީމެވެ. ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ގިނަގިނައިން ޝުކުރު ގަބޫލުކުރައްވާ ރަސްކަލާނގެއެވެ.","",""],["","","","أم يقولون افترى على الله كذبا فإن يشإ الله يختم على قلبك ويمح الله الباطل ويحق الحق بكلماته إنه عليم بذات الصدور","ނުވަތަ އެކަލޭގެފާނު ﷲއާމެދު އިތުރުފުޅެއް ހެއްދެވީކަމަށް އެއުރެން ބުނަނީހެއްޔެވެ؟ ފަހެ، ﷲ އިރާދަކުރައްވާނަމަ، ކަލޭގެފާނުގެ ހިތްޕުޅުގައި ސިއްކަގައްސަވައިފީހެވެ. އަދި ﷲ، ބާތިލު ފުއްސަވައި، އެކަލާނގެ ކަލިމަ ފުޅުތަކުން ހައްގު ސާބިތުކުރައްވަތެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ހިތްތަކުގައި ވާހާކަންތައް މޮޅަށްދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وهو الذي يقبل التوبة عن عباده ويعفو عن السيئات ويعلم ما تفعلون","އެކަލާނގެއީ، އެކަލާނގެ އަޅުތަކުންގެ ކިބައިން ތައުބާ ގަބޫލުކުރައްވައި، ނުބައިކަންތަކަށް އަފޫކުރައްވާ ރަސްކަލާނގެއެވެ. އަދި ތިޔަބައިމީހުންކުރާ ކަންތައްތައް، އެކަލާނގެ ދެނެވޮޑިގެންވެއެވެ.","",""],["","","","ويستجيب الذين آمنوا وعملوا الصالحات ويزيدهم من فضله والكافرون لهم عذاب شديد","އަދި އީމާންވެ، ސާލިހު ޢަމަލުތައްކުޅަ މީހުންނަށް އެކަލާނގެ އިޖާބަދެއްވައި، އެކަލާނގެ ފަޟްލު ވަންތަކަމުގެ ތެރެއިން އިތުރުކޮށްދެއްވަތެވެ. އަދި ކާފިރުންނަށް ގަދަވެގެންވާ އަޒާބު ހުށްޓެވެ.","",""],["","","","ولو بسط الله الرزق لعباده لبغوا في الأرض ولكن ينزل بقدر ما يشاء إنه بعباده خبير بصير","ﷲ، އެކަލާނގެ (އެންމެހައި) އަޅުންނަށް ރިޒްގު ތަނަވަސްކޮށްދެއްވައިފިނަމަ، ބިމުގައި އެއުރެން ބޮޑާވެ، އަނިޔާވެރިވެގެންފީހެވެ. އެހެނެއްކަމަކު، އެކަލާނގެ ރިޒްގު ބާވައިލައްވަނީ، އެކަލާނގެ އިރާދަކުރައްވާ ގޮތަކަށް ވަކިމިންވަރަކަށެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، އެކަލާނގެ އަޅުތަކުންގެ ޚަބަރުތައް މޮޅަށް ދެނެވޮޑިގެންވާ، މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وهو الذي ينزل الغيث من بعد ما قنطوا وينشر رحمته وهو الولي الحميد","އެކަލާނގެއީ، އެއުރެންގެ އުންމީދު ކެނޑުމަށްފަހު، ވާރޭވެއްސަވައި، އެކަލާނގެ ރަހުމަތް ފަތުރުއްވާ ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެއީ، ގިނަގިނައިން ހަމްދު ލިބިވޮޑިގެންވާ، އެހީތެރިވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ومن آياته خلق السماوات والأرض وما بث فيهما من دابة وهو على جمعهم إذا يشاء قدير","އަދި އުޑުތަކާއި، ބިމާއި، އެ ދެތާނގައި ފަތުރުއްވާފައިވާ ދިރޭތަކެތި ހެއްދެވުމީ، އެކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެކިތަކުގެ ތެރެއިންވާ ކަމެކެވެ. އަދި އެކަލާނގެއީ، އެކަލާނގެ އިރާދަކުރައްވާހިނދު، އެތަކެތި އެއްކުރެއްވުމަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وما أصابكم من مصيبة فبما كسبت أيديكم ويعفو عن كثير","ތިޔަބައިމީހުންނަށް ޖެހޭހާ މުސީބަތެއް ޖެހެނީ، ތިޔަބައިމީހުންގެ އަތްތަކުން ހޯދިކަންތަކުގެ ސަބަބުންނެވެ. އަދި އެކަލާނގެ ގިނަފާފަތައް އަފޫކުރައްވަތެވެ.","",""],["","","","وما أنتم بمعجزين في الأرض وما لكم من دون الله من ولي ولا نصير","އަދި ތިޔަބައިމީހުންނީ، ބިމުގައި (ﷲ) ނުކުޅައްދައި، ރެކިގެންދާނޭ ބަޔަކުކަމުގައި ނުވެތެވެ. އަދި ތިޔަބައިމީހުންނަކަށް ﷲ ފިޔަވައި އެއްވެސް އެހީތެރިޔަކު، އަދި ނަސްރު ދޭނޭމީހަކުވެސް ނުވެތެވެ.","",""],["","","","ومن آياته الجوار في البحر كالأعلام","އަދި ކަނޑުގައިދުވާ ފަރުބަދަތައްފަދަ އުޅަނދުތަކަކީ، އެކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ހެކިތަކުގެ ތެރެއިންވާ ތަކެއްޗެވެ.","",""],["","","","إن يشأ يسكن الريح فيظللن رواكد على ظهره إن في ذلك لآيات لكل صبار شكور","އެކަލާނގެ އިރާދަކުރައްވާނަމަ، ވައިމަޑުކުރައްވައިފީހެވެ. ފަހެ، އޭރުން އެއުޅަނދުތައް ފެންމަތީގައި ހުއްޓިހުރެދާނެތެވެ. ހަމަކަށަވަރުން، ކެތްތެރިކަންބޮޑު، ޝުކުރުވެރިވުންގިނަ ކޮންމެ މީހަކަށް އެކަންތަކުގައި ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","أو يوبقهن بما كسبوا ويعف عن كثير","ނުވަތަ އެއުރެން ހޯދި ނުބައިކަންތަކުގެ ސަބަބުން އެ އުޅަނދުތައް ހަލާކުކުރައްވައިފީހެވެ. އަދި (އެކަލާނގެ އިރާދަކުރައްވާނަމަ، އެއުރެންގެ) ގިނަ ފާފަ އަފޫކުރައްވައިފީހެވެ.","",""],["","","","ويعلم الذين يجادلون في آياتنا ما لهم من محيص","އަދި ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާމެދުގައި ޖަދަލުކުރާ މީހުންނަށް (ތިމަންރަސްކަލާނގެ އަޒާބުން) ފިލަންދާނޭ ތަނެއްނެތްކަން އެނގުމަށްޓަކައެވެ.","",""],["","","","فما أوتيتم من شيء فمتاع الحياة الدنيا وما عند الله خير وأبقى للذين آمنوا وعلى ربهم يتوكلون","ފަހެ، ތިޔަބައިމީހުންނަށް ދެއްވި ކޮންމެ އެއްޗަކީ، ދުނިޔޭގެ ދިރިއުޅުމުގެ ވަގުތީ އުފަލެކެވެ. އަދި އީމާންވެ، އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ވަކީލުކުރާމީހުންނަށް، ﷲގެ ހަޒުރަތު ގައިވާ ސަވާބު ހެޔޮކަންބޮޑެވެ. އަދި ދެމިހުރުން ބޮޑުމެއެވެ.","",""],["","","","والذين يجتنبون كبائر الإثم والفواحش وإذا ما غضبوا هم يغفرون","އަދި އެއުރެންނީ ބޮޑެތިފާފަތަކާއި، ފާޙީޝް ކަންތައްތަކުން ދުރުހެލިވެ ތިބޭމީހުންނެވެ. އަދި އެއުރެންނީ ރުޅިއަތުވެއްޖެހިނދެއްގައި މާފުކުރާ ބަޔެކެވެ.","",""],["","","","والذين استجابوا لربهم وأقاموا الصلاة وأمرهم شورى بينهم ومما رزقناهم ينفقون","އަދި އެއުރެންނީ، އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް އިޖާބަދީ، އަދި ނަމާދު ގާއިމުކުރިމީހުންނެވެ. އަދި އެއުރެންގެ ކަންތައްތައް، އެއުރެންގެ މެދުގައިވަނީ މަޝްވަރާގެ މަތިންނެވެ. އަދި ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްވިތަކެތިން، އެއުރެން ހޭދަކުރެތެވެ.","",""],["","","","والذين إذا أصابهم البغي هم ينتصرون","އަދި އެއުރެންނީ، އެއުރެންނަށް އަނިޔާވެރިވުމެއް އަންނަހިނދު، ނަސްރު ލިބިގަންނަ މީހުންނެވެ.","",""],["","","","وجزاء سيئة سيئة مثلها فمن عفا وأصلح فأجره على الله إنه لا يحب الظالمين","ނުބައިކަމެއްގެ ޖަޒާއަކީ އެއާއެއްފަދަ ނުބައިކަމެކެވެ. ފަހެ (ނުބައިކަމެއް ކޮށްފިމީހާއަށް) އަފޫ ކޮށް، ސުލްހަވެރިވެގަތްމީހާގެ ސަވާބު ވަނީ، ﷲގެ ހަޒުރަތު ގައެވެ. ހަމަކަށަވަރުން، އެކަލާނގެ، އަނިޔާވެރިންދެކެ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["","","","ولمن انتصر بعد ظلمه فأولئك ما عليهم من سبيل","އަނިޔާލިބުމަށްފަހު، ނަސްރު ލިބިގެންފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންގެ މައްޗަކަށް ކުށްވެރިކުރުމުގެ އެއްވެސް މަގެއްނެތެވެ.","",""],["","","","إنما السبيل على الذين يظلمون الناس ويبغون في الأرض بغير الحق أولئك لهم عذاب أليم","އެކަމަކު، ކުށްވެރިކުރުމުގެ މަގެއް އޮތްކަން ކަށަވަރީ، މީސްތަކުންނަށް އަނިޔާވެރިވެ، އަދި ބިމުގައި ހައްގަކާނުލައި ބަޣާވާތް ތެރިވެ، ފަސާދަކުރާ މީހުންގެ މައްޗަށެވެ. އެއުރެންނަށް ވޭންދެވިނި އަޒާބު ހުށްޓެވެ.","",""],["","","","ولمن صبر وغفر إن ذلك لمن عزم الأمور","އަދި ހަމަކަށަވަރުން، ކެތްތެރިވެ، އަފޫކުރިމީހާ (ދަންނާށެވެ!) ހަމަކަށަވަރުން، އެކަންކަންވަނީ، ޢަޒުމު ކަނޑައަޅަންޖެހޭ ކަންތައްތަކުގެ ތެރެއިންކަން ކަށަވަރެވެ.","",""],["","","","ومن يضلل الله فما له من ولي من بعده وترى الظالمين لما رأوا العذاب يقولون هل إلى مرد من سبيل","ﷲ، އެމީހަކު މަގުފުރައްދަވާމީހާ (ދަންނާށެވެ!) ފަހެ، އެކަލާނގެ ފިޔަވައި އޭނާޔަށް އެއްވެސް އެހީތެރިޔަކު ނުވާނެތެވެ. އަދި އަނިޔާވެރިންނަށް އަޒާބު ފެންނަހިނދު، އެއުރެން ބުނާތީ ތިބާ ދެކޭނޫއެވެ. ދުނިޔެއަށް އަލުން އެނބުރި ދިޔުމަށް، އެއްވެސް މަގެއްވޭހެއްޔެވެ؟","",""],["","","","وتراهم يعرضون عليها خاشعين من الذل ينظرون من طرف خفي وقال الذين آمنوا إن الخاسرين الذين خسروا أنفسهم وأهليهم يوم القيامة ألا إن الظالمين في عذاب مقيم","އަދި ނިކަމެތިވެ، ބިރުގެން، ވައްކަޅިން ބަލާ ޙާލު، އެއުރެން ނަރަކަޔަށް ހުށަހަޅުއްވާތީ ތިބާދެކޭނޫއެވެ. އަދި އީމާން ވިމީހުން ބުނާނެތެވެ. ހަމަކަށަވަރުން، ގެއްލުންވިމީހުންނީ، ގިޔާމަތް ދުވަހުގައި، އެއުރެންގެ އަމިއްލަ ނަފްސު ތަކާއި، އަހުލުވެރިން ގެއްލެނިކުޅަ މީހުންނެވެ. ދަންނާށެވެ! ހަމަކަށަވަރުން، އަނިޔާވެރިންވަނީ، ދެމިހުންނަނިވި އަޒާބެއްގައެވެ.","",""],["","","","وما كان لهم من أولياء ينصرونهم من دون الله ومن يضلل الله فما له من سبيل","އަދި ﷲ ފިޔަވައި، އެއުރެންނަށް ނަސްރު ދޭނޭ އެއްވެސް އެހީތެރިޔަކު، އެއުރެންނަކަށް ނުވާހުށްޓެވެ. އަދި ﷲ މަގުފުރައްދަވާމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް (ސަލާމަތްވާނޭ) އެއްވެސްމަގެއް ނުވެތެވެ.","",""],["","","","استجيبوا لربكم من قبل أن يأتي يوم لا مرد له من الله ما لكم من ملجإ يومئذ وما لكم من نكير","ﷲގެ ހަޒުރަތުން ރައްދުނުކުރެވޭނެ ދުވަހެއް (އެބަހީ: ގިޔާމަތް ދުވަސް) އައުމުގެކުރިން، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއަށް ތިޔަބައިމީހުން އިޖާބަދޭށެވެ! އެދުވަހުން ތިޔަބައިމީހުން ސަލާމަތްވާންދާނެ އެއްވެސްތަނެއް، ތިޔަބައިމީހުންނަކަށް ނުވެތެވެ. އަދި (ތިޔަބައިމީހުންގެ އަޒާބަށް) އިންކާރުކުރާނޭ މީހަކުވެސް ތިޔަބައިމީހުންނަކަށް ނުވެތެވެ.","",""],["","","","فإن أعرضوا فما أرسلناك عليهم حفيظا إن عليك إلا البلاغ وإنا إذا أذقنا الإنسان منا رحمة فرح بها وإن تصبهم سيئة بما قدمت أيديهم فإن الإنسان كفور","ފަހެ، އެއުރެން ފުރަގަސްދީފިނަމަ (ދަންނާށެވެ!) ފަހެ، އެއުރެންގެ މައްޗަށް ބެލެހެއްޓުންތެރިޔަކު ކަމުގައި ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނު ނުފޮނުއްވަމެވެ. އިއްވެވުންމެނުވީ ކަލޭގެފާނުގެ މައްޗަކަށް ނުވެތެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ރަހުމަތެއްގެ ރަހަ ތިމަންރަސްކަލާނގެ އިންސާނާއަށް ދައްކަވައިފިނަމަ، އެކަމަށް އޭނާ އުފާކުރެތެވެ. އަދި އެއުރެންގެ އަތްތަކުން އިސްކުރި ފާފަތަކުގެ ސަބަބުން އެއުރެންނަށް ނުބައިކަމެއް ޖެހިއްޖެނަމަ ފަހެ، ހަމަކަށަވަރުން، އިންސާނާއީ (ނިއުމަތްތަކަށް) ދެކޮޅުހަދާ، ކާފިރު ވާމީހެކެވެ.","",""],["","","","لله ملك السماوات والأرض يخلق ما يشاء يهب لمن يشاء إناثا ويهب لمن يشاء الذكور","އުޑުތަކާއި، ބިމުގެ ވެރިކަންވަނީ ﷲއަށެވެ. އެކަލާނގެ އިރާދަކުރައްވާ އެއްޗެއް އެކަލާނގެ ހައްދަވަތެވެ. އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް އަންހެންދަރިން ދެއްވަތެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ފިރިހެންދަރިން ދެއްވަތެވެ.","",""],["","","","أو يزوجهم ذكرانا وإناثا ويجعل من يشاء عقيما إنه عليم قدير","ނުވަތަ އެއުރެންނަށް ފިރިހެންދަރިންނާއި، އަންހެންދަރިން ދެއްވަތެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވާމީހަކު، ދަރިމައިނުވާމީހަކު ކަމުގައި ލައްވަތެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، މޮޅަށްދެނެވޮޑިގެންވާ، ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وما كان لبشر أن يكلمه الله إلا وحيا أو من وراء حجاب أو يرسل رسولا فيوحي بإذنه ما يشاء إنه علي حكيم","ވަހީއަކުން (އެބަހީ: އިލްހާމަކުން، ނުވަތަ ހުވަފެނަކުން) ނުވަތަ ފަރުދާއެއްގެ އަނެއްފަރާތުން، ނުވަތަ މަލާއިކަތަކު ފޮނުއްވައި، އެކަލާނގެ އިޒުނަ ފުޅާއެކު، އެކަލާނގެ އިރާދަކުރައްވާ އެއްޗެއް ވަހީކުރެއްވުމުންމެނުވީ، އެއްވެސް އާދަމުގެދަރިޔަކަށް ﷲ ބަސް ވަހީކުރެއްވުމެއް ނުވެތެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، މަތިވެރިވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وكذلك أوحينا إليك روحا من أمرنا ما كنت تدري ما الكتاب ولا الإيمان ولكن جعلناه نورا نهدي به من نشاء من عبادنا وإنك لتهدي إلى صراط مستقيم","އަދި ހަމައެފަދައިން ތިމަންރަސްކަލާނގެ އަމުރުފުޅުން ކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ ގުރުއާން ވަހީކުރެއްވީމެވެ. ފޮތަކީ ކޮންއެއްޗެއްކަން، އަދި އީމާނަކީ ކޮންއެއްޗެއްކަން ކަލޭގެފާނު (ކުރިން) ދެނެވަޑައިގަންނަވާ ކަމުގައި ނުވެތެވެ. އެހެނެއްކަމަކު، ތިމަންރަސްކަލާނގެ އަޅުންގެ ތެރެއިން ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާ ބަޔަކަށް، ތިމަންރަސްކަލާނގެ، އެއިން ތެދުމަގު ދައްކަވާ ނޫރެއްކަމުގައި އެ ގުރްއާން ލެއްވީމެވެ. އަދި ހަމަކަށަވަރުން، ކަލޭގެފާނު މަގުދައްކަވަނީ، ސީދާވެގެންވާ ތެދުމަގަށްކަން ކަށަވަރެވެ.","",""],["","","","صراط الله الذي له ما في السماوات وما في الأرض ألا إلى الله تصير الأمور","(އެއީ) ﷲގެ މަގެވެ. އެކަލާނގެއީ، އުޑުތަކާއި، ބިމުގައިވާހާ އެއްޗެއް މިލްކުވެގެންވާ ރަސްކަލާނގެއެވެ. ދަންނާށެވެ! ކަންތައްތައް ރުޖޫއަ ވާހުށީ ﷲގެ ހަޒުރަތަށެވެ.","",""],["","","","بسم الله الرحمن الرحيم حم","ح م (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","والكتاب المبين","ބަޔާން ވެގެންވާ ފޮތް ގަންދެއްވައި ވަހީކުރައްވަމެވެ.","",""],["","","","إنا جعلناه قرآنا عربيا لعلكم تعقلون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެފޮތް ލައްވާފައިވަނީ، އަރަބި ބަހުންއޮތް ގުރްއާނެއް ކަމުގައެވެ. އެއީ ތިޔަބައިމީހުން ވިސްނުމަށްޓަކައެވެ.","",""],["","","","وإنه في أم الكتاب لدينا لعلي حكيم","އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ހަޒުރަތު ގައިވާ މައިފޮތުގައި (އެބަހީ: އައްލައުޙުލް މަޙްފޫޡުގައި) އެފޮތްވަނީ މަތިވެރިވެގެންވާ ހިކުމަތް ތެރި ފޮތެއް ކަމުގައެވެ.","",""],["","","","أفنضرب عنكم الذكر صفحا أن كنتم قوما مسرفين","ފަހެ، ތިޔަބައިމީހުން (ކާފިރުކަމުގައި) ހައްދުފަހަނަޅައިފައިވާ ބަޔަކު ކަމުގައިވީތީވެ، ތިޔަބައިމީހުންނާމެދު ތިމަންރަސްކަލާނގެ ގުރްއާންގެ ވައުޒު ބާވައިނުލައްވައި ދޫކޮށްލައްވަންވީހެއްޔެވެ؟","",""],["","","","وكم أرسلنا من نبي في الأولين","އަދި އިސްވެދިޔަ މީސްތަކުންގެގާތަށް ތިމަންރަސްކަލާނގެ ކިތައްކިތައް ނަބިއްޔުން ފޮނުއްވިން ހެއްޔެވެ؟","",""],["","","","وما يأتيهم من نبي إلا كانوا به يستهزئون","އަދި އެއުރެން އެބޭކަލަކަށް ފުރައްސާރަކުރާ ކަމުގައިނުވާ އެއްވެސް ނަބިއްޔަކު އެއުރެންގެ ގާތަކަށް ވަޑައެއްނުގަންނަވަތެވެ.","",""],["","","","فأهلكنا أشد منهم بطشا ومضى مثل الأولين","ފަހެ، ތިމަންރަސްކަލާނގެ އެބައިމީހުންނަށްވުރެ މާބާރުގަދަ މީހުން ހަލާކު ކުރެއްވީމެވެ. އަދި އިސްވެދިޔަ މީހުންގެ މިސާލު ވޭތުވެހިނގައްޖެއެވެ.","",""],["","","","ولئن سألتهم من خلق السماوات والأرض ليقولن خلقهن العزيز العليم","ހަމަކަށަވަރުން، އުޑުތަކާއި، ބިން ހެއްދެވީ ކާކުހޭ، ކަލޭގެފާނު އެއުރެންނާ ސުވާލުކުރައްވައިފިނަމަ، އެއުރެން ބުނާނެކަން ކަށަވަރެވެ. އެތަކެތި ހެއްދެވީ، ޢަޒީޒުވަންތަ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","الذي جعل لكم الأرض مهدا وجعل لكم فيها سبلا لعلكم تهتدون","އެކަލާނގެއީ، ތިޔަބައިމީހުންނަށް ތަންމައްޗެއްކަމުގައި ބިން ލައްވައި، އަދި އެތާނގައި، ތިޔަބައިމީހުންނަށް މަގުތައް ލެއްވި ރަސްކަލާނގެއެވެ. (އެއީ) ތިޔަބައިމީހުން (ގަސްތުކުރާ ތަންތަނަށް) ދިއުމަށް މަގު އެނގުމަށްޓަކައެވެ.","",""],["","","","والذي نزل من السماء ماء بقدر فأنشرنا به بلدة ميتا كذلك تخرجون","އަދި އެކަލާނގެއީ، ކަނޑައެޅިގެންވާ މިންވަރަކަށް އުޑުން ފެން ވެއްސެވި ރަސްކަލާނގެއެވެ. ފަހެ، މަރުވެފައިވާ ރަށެއް ތިމަންރަސްކަލާނގެ އެފެނުން ދިރުއްވީމެވެ. ހަމައެފަދައިން، ތިޔަބައިމީހުން (ކަށްވަޅުތަކުން) ނެރުއްވާހުށްޓެވެ.","",""],["","","","والذي خلق الأزواج كلها وجعل لكم من الفلك والأنعام ما تركبون","އަދި އެކަލާނގެއީ، ހުރިހާ ބާވަތެއްގެ ތަކެތި ޖޯޑުޖޯޑަށް ހެއްދެވި ރަސްކަލާނގެއެވެ. އަދި ނައުފަހަރާއި، ނަޢަމް ސޫފީގެ ތެރެއިން ތިޔަބައިމީހުން ސަވާރުވާނޭތަކެތި، އެކަލާނގެ ތިޔަބައިމީހުންނަށްޓަކައި ލެއްވިއެވެ.","",""],["","","","لتستووا على ظهوره ثم تذكروا نعمة ربكم إذا استويتم عليه وتقولوا سبحان الذي سخر لنا هذا وما كنا له مقرنين","(އެއީ) ތިޔަބައިމީހުން އެތަކެތީގެ ބުރަކަށިމަތީގައި ހަމަޖެހުމަށްޓަކައެވެ. ދެން ތިޔަބައިމީހުން އޭގެމަތީގައި ހަމަޖެހޭހިނދު، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތް ހަނދުމަކުރުމަށެވެ. އަދި ތިޔަބައިމީހުން ކިޔުމަށްޓަކައެވެ. އަޅަމެންނަށް މި ތަކެތި ޚިދުމަތް ތެރިކޮށްދެއްވި ރަސްކަލާނގެ ހުސްތާހިރު ވަންތަކަމާއެވެ! އަދި އަޅަމެންއެކަމަށް ކުޅަދާނަވެގެންވާ ބަޔަކުކަމުގައި ނުވަމުއެވެ.","",""],["","","","وإنا إلى ربنا لمنقلبون","އަދި ހަމަކަށަވަރުން، އަޅަމެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް އަޅަމެން ރުޖޫއަ ވާނެކަން ކަށަވަރެވެ.","",""],["","","","وجعلوا له من عباده جزءا إن الإنسان لكفور مبين","އެއުރެން (އެބަހީ: ކާފިރުވި މީހުން) އެކަލާނގެ އަޅުންގެތެރެއިން ބަޔެއް، އެކަލާނގެ ދަރިންކަމުގައި ހެދޫއެވެ. ހަމަކަށަވަރުން (މިކަންކުރާ) އިންސާނާއީ، ފާޅުވެގެންހުރި ކާފިރު ކަންބޮޑު މީހެއްކަން ކަށަވަރެވެ.","",""],["","","","أم اتخذ مما يخلق بنات وأصفاكم بالبنين","ނުވަތަ އެކަލާނގެ ހެއްދެވި ތަކެތީގެތެރެއިން އެކަލާނގެ ޛާތު ފުޅަށް އަންހެންދަރިން ހިއްޕަވައި، ތިޔަބައިމީހުންނަށް ފިރިހެންދަރިން ހާއްސަކުރެއްވި (ކަމަށް ހީކުރަނީ) ހެއްޔެވެ؟","",""],["","","","وإذا بشر أحدهم بما ضرب للرحمن مثلا ظل وجهه مسودا وهو كظيم","ރަޙްމާންވަންތަ ރަސްކަލާނގެއަށް އެއުރެންގެ މީހަކު ނިސްބަތްކުރިފަދަ ދަރިޔަކު (އެބަހީ: އަންހެން ދަރިޔަކު) ލިބުނުކަމުގެ ޚަބަރު އެމީހަކަށް ދެވިއްޖެނަމަ، އޭނާގެ މޫނު އަނދިރިވެގެންދެއެވެ. އޭނާޔަށް އެކަމުގެ ހިތާމަ ލިބިގެންވާ ޙާލު ގައެވެ.","",""],["","","","أومن ينشأ في الحلية وهو في الخصام غير مبين","އަދި (ﷲއަށް އެއުރެން އެ ނިސްބަތްކުރަނީ) ގަހަނާ އަޅުވައި، ބޮޑުކުރާ މީހަކު ހެއްޔެވެ؟ އަދި އޭނާއީ، ދެކޮޅުވެރިކަމެއް ދިމާވާހިނދު ހުއްޖަތް ބަޔާން ނުކުރެވޭ މީހެކެވެ.","",""],["","","","وجعلوا الملائكة الذين هم عباد الرحمن إناثا أشهدوا خلقهم ستكتب شهادتهم ويسألون","އަދި ރަޙްމާންވަންތަ ރަސްކަލާނގެ އަޅުންކަމުގައިވާ މަލާއިކަތުންނަކީ، އަންހެން ބަޔެއް ކަމުގައި އެއުރެން ހެދީހެއްޔެވެ؟ އެ މަލާއިކަތުން ހެއްދެވިއިރު، އެއުރެން ޙާޒިރުުވެ ތިބީހެއްޔެވެ؟ އެއުރެން އެ ހެކިވާހެކިވުން، ނިކަންހުރެ ލިޔުއްވާހުށްޓެވެ. އަދި (އާޚިރަތް ދުވަހުން) އެއުރެންނާ ސުވާލުކުރައްވާހުށްޓެވެ.","",""],["","","","وقالوا لو شاء الرحمن ما عبدناهم ما لهم بذلك من علم إن هم إلا يخرصون","އަދި އެއުރެން ބުނޫއެވެ. ރަޙްމާންވަންތަ ރަސްކަލާނގެ އިރާދަކުރެއްވިނަމަ، ތިމަންމެން އެ މަލާއިކަތުންނަކަށް އަޅުކަމެއް ނުކުރީމުހެވެ. އެކަމާމެދު އެއުރެންނަށް އެއްވެސް އެނގުމެއް ނުވެތެވެ. އެއުރެން ދޮގުހަދާ ބަޔަކުކަމުގައި މެނުވީ ނުވެތެވެ.","",""],["","","","أم آتيناهم كتابا من قبله فهم به مستمسكون","ނުވަތަ އޭގެކުރިން (އެބަހީ: ގުރްއާންގެ ކުރިން) ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ފޮތެއް ދެއްވައި، ފަހެ، އެއުރެން އެފޮތުގައި ހިފަހައްޓަނީ ހެއްޔެވެ؟","",""],["","","","بل قالوا إنا وجدنا آباءنا على أمة وإنا على آثارهم مهتدون","އަދި ކިއެއްތަ! އެއުރެން ބުނޫއެވެ. ތިމަންމެންގެ ކާބަފައިން ދީނެއްގެ މަތީގައި ވަނިކޮށް ތިމަންމެން ހަމަކަށަވަރުން، ދުށީމުއެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެންގެ އަޘަރުތަކުގެ މަތީގައި ތިމަންމެން ހިނގަނީއެވެ.","",""],["","","","وكذلك ما أرسلنا من قبلك في قرية من نذير إلا قال مترفوها إنا وجدنا آباءنا على أمة وإنا على آثارهم مقتدون","އަދި ހަމައެފަދައިން އެރަށެއްގައި ތިބި ތަނަވަސްކަމުގައި ހައްދުފަހަނަޅައި ގޮސްފައިވާ މީހުން ހަމަކަށަވަރުން، ތިމަންމެންގެ ކާބަފައިން ދީނެއްގެ މަތީގައި ވަނިކޮށް ތިމަންމެން ދުށީމުއޭ އަދި ހަމަކަށަވަރުން، އެއުރެންގެ އަޘަރުތަކުގެ މަތީގައި ތިމަންމެން ތަބާ ވެގެން ހިނގަމުއޭ ނުބުނާ އެއްވެސް ރަށަކަށް އިންޒާރުކުރެއްވުމަށް ކަލޭގެފާނުގެ ކުރިން ތިމަންރަސްކަލާނގެ އެއްވެސް ރަސޫލަކު ނުފޮނުއްވަމެވެ.","",""],["","","","قال أولو جئتكم بأهدى مما وجدتم عليه آباءكم قالوا إنا بما أرسلتم به كافرون","އެބޭކަލަކު ވިދާޅުވިއެވެ. ތިޔަބައިމީހުންގެ ކާބަފައިން އެ ދީނެއްގެ މަތީގައި ވަނިކޮށް ތިޔަބައިމީހުން ދުށް ދީނަށްވުރެ ހައްގު ކަންބޮޑު ދީނަކާއިގެން ތިޔަބައިމީހުންގެ ގާތަށް، ތިމަންކަލޭގެފާނު ވަޑައިގަތްކަމުގައިވިޔަސް ހެއްޔެވެ؟ އެއުރެން ބުނޫއެވެ. ހަމަކަށަވަރުން، އެ ދީނަކާއިގެން ތިޔަބޭކަލުން ފޮނުއްވެވި ދީނަށް ތިމަންމެންވަނީ ކާފިރު ވެގެންނެވެ.","",""],["","","","فانتقمنا منهم فانظر كيف كان عاقبة المكذبين","ފަހެ، ތިމަންރަސްކަލާނގެ އެއުރެންގެކިބައިން ބަދަލުހިއްޕެވީމެވެ. ފަހެ، ދޮގުކުރާ މީހުންގެ ނިމުންވަނީ ކޮންފަދައަކުންކަން ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާށެވެ!","",""],["","","","وإذ قال إبراهيم لأبيه وقومه إنني براء مما تعبدون","އިބްރާހީމްގެފާނު، އެކަލޭގެފާނުގެ ބައްޕައަށާއި، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް ވިދާޅުވިހިނދު ހަނދުމަކުރާށެވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުން އަޅުކަންކޮށްއުޅޭ ތަކެތިން ތިމަންކަލޭގެފާނު ބަރީއަވެގެންވަމެވެ.","",""],["","","","إلا الذي فطرني فإنه سيهدين","އިސްވެދިޔަ މިސާލަކާނުލައި ތިމަން ހެއްދެވި ރަސްކަލާނގެ މެނުވީއެވެ. ފަހެ، ހަމަކަށަވަރުން، އެކަލާނގެ ތިމަންކަލޭގެފާނަށް ތެދުމަގު ދައްކަވާނެތެވެ.","",""],["","","","وجعلها كلمة باقية في عقبه لعلهم يرجعون","އަދި އެބަސްފުޅު (އެބަހީ: لاإله إلاّاللَّه މި ކަލިމަފުޅު) އެކަލޭގެފާނުގެ ދަރިކޮޅުގައި ދެމިއޮންނާނޭ ބަސްފުޅެއްކަމުގައި ލެއްވިއެވެ. އެއީ ﷲގެ މަގަށް އެއުރެން ރުޖޫއަ ވުމަށްޓަކައެވެ.","",""],["","","","بل متعت هؤلاء وآباءهم حتى جاءهم الحق ورسول مبين","އަދި ކިއެއްތަ! ތިމަންރަސްކަލާނގެ މިބައިމީހުންނާއި، އެއުރެންގެ ކާބަފައިން އަރާމުގައި އުޅުމަށް ލެހެއްޓެވީމެވެ. ހައްގު ފޮތާއި، ބަޔާން ކޮށްދެއްވާ ރަސޫލަކު އެއުރެންގެގާތަށް ވަޑައިގެންފުމަށް ދާނދެނެވެ.","",""],["","","","ولما جاءهم الحق قالوا هذا سحر وإنا به كافرون","އަދި ހައްގު ފޮތް (އެބަހީ: ކީރިތި ގުރްއާން) އެއުރެންގެ ގާތަށް އައިހިނދު، އެއުރެން ބުނޫއެވެ. މިއީ ޖާދޫއެކެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންމެންވަނީ، އެއަށް ކާފިރު ވެގެންނެވެ.","",""],["","","","وقالوا لولا نزل هذا القرآن على رجل من القريتين عظيم","އަދި އެއުރެން ބުނޫއެވެ. އެ ދެރަށުގެ (އެބަހީ: މައްކާއާއި، ޠާއިފުގެ) މީހުންކުރެ، މާތްމީހަކަށް މި ގުރްއާން ބާވައިނުލެއްވީ ކީއްވެގެން ހެއްޔެވެ؟","",""],["","","","أهم يقسمون رحمت ربك نحن قسمنا بينهم معيشتهم في الحياة الدنيا ورفعنا بعضهم فوق بعض درجات ليتخذ بعضهم بعضا سخريا ورحمت ربك خير مما يجمعون","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ރަހުމަތް ބަހައިދެނީ އެއުރެން ހެއްޔެވެ؟ (އެބަހީ: އެއުރެން ބޭނުން މީހަކަށް ނަބީކަންދެނީ އެއުރެން ހެއްޔެވެ؟) ދުނިޔޭގެ ދިރިއުޅުމުގައި އެއުރެންގެމެދުގައި ދިރިއުޅުމުގެ ކަންތައްތައް ބެއްސެވީ ތިމަންރަސްކަލާނގެއެވެ. އަދި ތިމަންރަސްކަލާނގެ އެއުރެންކުރެ ބައެއްމީހުން، އަނެއްބައިމީހުންގެ މައްޗަށް ދަރަޖަތަކަކަށް އުފުއްލެވީމެވެ. (އެއީ) އެއުރެންކުރެ އެއްބަޔަކު އަނެއްބަޔެއްގެ ޚިދުމަތް ތެރިކަން ހިފުމަށްޓަކައެވެ. އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ރަހުމަތެއުރެން އެއްކުރާތަކެއްޗަށްވުރެ ހެޔޮކަން ބޮޑެވެ.","",""],["","","","ولولا أن يكون الناس أمة واحدة لجعلنا لمن يكفر بالرحمن لبيوتهم سقفا من فضة ومعارج عليها يظهرون","އަދި (ކާފިރުކަމުގައި) މީސްތަކުން އެއް އުއްމަތެއްކަމުގައި ނުވާނެނަމަ، ރަޙްމާންވަންތަ ރަސްކަލާނގެއަށް ކާފިރުވާ މީހުންގެ ގެތަކުގެ ފުރާޅުތައް ރިހިން ލައްވައި، އަދި އެއުރެން އަރައިފައިބާ ސިޑިތައް (ރިހިން) ލެއްވީމުހެވެ.","",""],["","","","ولبيوتهم أبوابا وسررا عليها يتكئون","އަދި އެއުރެންގެ ގެތަކުގެ ދޮރުތަކާއި، އެއުރެން ލެނގިލައިގެން ތިބޭ އެނދުތައްވެސް (ރިހިން) ލެއްވީމުހެވެ.","",""],["","","","وزخرفا وإن كل ذلك لما متاع الحياة الدنيا والآخرة عند ربك للمتقين","އަދި (އެތަކެއްޗަށް) ޒީނަތްތެރިކަން ލެއްވީމުހެވެ. އެހުރިހާ ތަކެއްޗަކީ، ދުނިޔޭގެ ދިރިއުޅުމުގެ ވަގުތީ އަރާމެއްކަމުގައިނޫނީ ނުވެތެވެ. އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ތަގުވާވެރިންނަށް އާޚިރަތްގެ ނިއުމަތް ހުށްޓެވެ.","",""],["","","","ومن يعش عن ذكر الرحمن نقيض له شيطانا فهو له قرين","ރަޙްމާންވަންތަ ރަސްކަލާނގެ ހަނދުމަކުރުމަށް ކަނުވެގަންނަ މީހާއަށް ތިމަންރަސްކަލާނގެ ޝައިތާނެއް ފާކުރައްވާހުށީމެވެ. ފަހެ، ޝައިތާނާ އޭނާޔާ ވަކިނުވެ، އެކުގައި އުޅޭނެތެވެ.","",""],["","","","وإنهم ليصدونهم عن السبيل ويحسبون أنهم مهتدون","އަދި ހަމަކަށަވަރުން، އެ ޝައިތާނުން، މީސްތަކުން ތެދުމަގުން އެއްކިބާކުރެތެވެ. އަދި އެއުރެން ހީކުރަނީ، އެއުރެންވަނީ ތެދުމަގު ލިބިފައިކަމުގައެވެ.","",""],["","","","حتى إذا جاءنا قال يا ليت بيني وبينك بعد المشرقين فبئس القرين","އޭނާ ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް އަތުވެއްޖެނަމަ، އެހިނދު އޭނާ ބުނާނެތެވެ. ތިމަންނާޔާ، ކަލެޔާ ދެމެދުގެ ދުރުމިން މަޝްރިގާއި، މަޣްރިބާ ދެމެދުހައި ދުރުމިން ކަމުގައިވާނަމަ، ކޮންފަދަހެއްޔެވެ! ފަހެ، ކަލެޔަކީ ހާދަހާ ނުބައިވެގެންވާ އެކުވެރިޔެކެވެ.","",""],["","","","ولن ينفعكم اليوم إذ ظلمتم أنكم في العذاب مشتركون","(އެއުރެންނަށް އަންގަވާނެތެވެ.) އަދި ތިޔަބައިމީހުން އަނިޔާވެރިވުމުގެ ސަބަބުން، ތިޔަބައިމީހުން އަޒާބުގައި ބައިވެރިވުމަކުން މިއަދު ތިޔަބައިމީހުންނަކަށް މަންފާއެއް ނުކުރާނެތެވެ.","",""],["","","","أفأنت تسمع الصم أو تهدي العمي ومن كان في ضلال مبين","ފަހެ، ބީރުބަޔަކަށް (ހައްގުގެ) އަޑު ކަލޭގެފާނަށް އިއްވެވިދާނެތޯއެވެ؟ ނުވަތަ ކަނުބަޔަކަށް އަދި ފާޅުވެ ބަޔާން ވެގެންވާ އުރެދުމެއްގައިވާ ބަޔަކަށް މަގު ދެއްކެވިދާނެތޯއެވެ؟","",""],["","","","فإما نذهبن بك فإنا منهم منتقمون","ފަހެ، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ގެންދަވައިފިނަމަވެސް (އެބަހީ: މަރުގެންނެވި ނަމަވެސް) ފަހެ، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެންގެ ކިބައިން ބަދަލުހިއްޕަވާ ހުށީމެވެ.","",""],["","","","أو نرينك الذي وعدناهم فإنا عليهم مقتدرون","ނުވަތަ އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ވައުދުކުރެއްވި ކަންތައް ކަލޭގެފާނަށް ދައްކަވާހުށީމެވެ. ފަހެ، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެއީ، އެއުރެންގެމައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","فاستمسك بالذي أوحي إليك إنك على صراط مستقيم","ފަހެ، ކަލޭގެފާނަށް އިއްވަވާ ވަހީއެއްގައި ކަލޭގެފާނު ހިފަހައްޓަވާށެވެ! ހަމަކަށަވަރުން، ކަލޭގެފާނުވަނީ، ސީދާވެގެންވާ ތެދުމަގެއްގެ މަތީގައެވެ.","",""],["","","","وإنه لذكر لك ولقومك وسوف تسألون","އަދި ހަމަކަށަވަރުން، އެ ގުރްއާނަކީ ކަލޭގެފާނަށާއި، ކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް ލިބުނު ޝަރަފެކެވެ. އަދި ނިކަންހުރެ ތިޔަބައިމީހުންނާ ސުވާލުކުރައްވާނެތެވެ.","",""],["","","","واسأل من أرسلنا من قبلك من رسلنا أجعلنا من دون الرحمن آلهة يعبدون","އަދި ތިމަންރަސްކަލާނގެ ރަސޫލުންގެ ތެރެއިން ކަލޭގެފާނުގެ ކުރިން ތިމަންރަސްކަލާނގެ ފޮނުއްވި ރަސޫލު ންކުރެން އައްސަވާށެވެ! (އެބަހީ: އެބޭކަލުންގެ ޝަރީޢަތުން ބައްލަވާށެވެ!) ރަޙްމާންވަންތަ ރަސްކަލާނގެ މެނުވީ، އަޅުކަންވެވޭ އެހެން އިލާހުންތަކެއް ތިމަންރަސްކަލާނގެ ލެއްވިންހެއްޔެވެ؟","",""],["","","","ولقد أرسلنا موسى بآياتنا إلى فرعون وملئه فقال إني رسول رب العالمين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާއިގެން، ފިރްޢައުނާއި، އޭނާގެ ގައުމުގެ ބޮޑުންގެ ގާތަށް ތިމަންރަސްކަލާނގެ މޫސާގެފާނު ފޮނުއްވީމެވެ. ފަހެ، އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނީ، އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ރަސޫލަކީމެވެ.","",""],["","","","فلما جاءهم بآياتنا إذا هم منها يضحكون","ފަހެ، އެކަލޭގެފާނު ތިމަންރަސްކަލާނގެ އާޔަތް ތަކާއިގެން އެއުރެންގެގާތަށް ވަޑައިގަތްހިނދު، އެހާރުން އެ އާޔަތް ތަކާމެދު، އެއުރެން މަލާމާތްކޮށް، ހެނއެވެ.","",""],["","","","وما نريهم من آية إلا هي أكبر من أختها وأخذناهم بالعذاب لعلهم يرجعون","އަދި އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ދެއްކެވި ކޮންމެ މުއުޖިޒާއެއް، އެފަދަ އަނެއް މުއުޖިޒާއަކަށްވުރެ މާބޮޑުކަމުގައި މެނުވީ ނުދައްކަވަމެވެ. އަދި ތިމަންރަސްކަލާނގެ އެއުރެންނަށް އަޒާބު ދެއްވައި، ހިއްޕެވީމެވެ. (އެއީ) އެއުރެން (ކާފިރުކަމުން) ރުޖޫއަ ވުމަށްޓަކައެވެ.","",""],["","","","وقالوا يا أيه الساحر ادع لنا ربك بما عهد عندك إننا لمهتدون","އެއުރެން ބުނޫއެވެ. އޭ ޖާދޫވެރިޔާއެވެ! އެކަލާނގެ ކަލޭގެފާނަށް އަހުދު ވެވޮޑިގެންނެވި ކަންތައް ތިމަންމެންނަށް ދެއްވުމަށްއެދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް ދުއާކުރައްވައި ބައްލަވާށެވެ! ހަމަކަށަވަރުން، ތިމަންމެން ވާހުށީ ތެދުމަގުލިބިގެންވާ ބަޔަކު ކަމުގައެވެ.","",""],["","","","فلما كشفنا عنهم العذاب إذا هم ينكثون","ފަހެ، ތިމަންރަސްކަލާނގެ އެއުރެންގެ ކިބައިން އަޒާބު ފިއްލަވައިފިހިނދު، އެހާރުން އެއުރެން އަހުދު އުވައިލަތެވެ.","",""],["","","","ونادى فرعون في قومه قال يا قوم أليس لي ملك مصر وهذه الأنهار تجري من تحتي أفلا تبصرون","އަދި ފިރްޢައުނު އޭނާގެ ގައުމުގެމީހުންގެ ތެރޭގައި ހުރެ ގޮވައިލިއެވެ. އޭނާ ބުންޏެވެ. އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! މިސްރުގެ ވެރިކަންވަނީ ތިމަންނާއަކަށް ނޫންހެއްޔެވެ؟ އަދި މި ކޯރުތައް ތިމަންގެ ދަށުން ހިނގަހިނގާ ހުރެތެވެ. ފަހެ، ތިޔަބައިމީހުންނަށް ނުފެންނަނީ ހެއްޔެވެ؟","",""],["","","","أم أنا خير من هذا الذي هو مهين ولا يكاد يبين","އަދި ކީއްހެއްޔެވެ؟ މިހިރަ ދެރަނިކަމެތި މީހާއަށްވުރެ (އެބަހީ: މޫސާގެފާނަށްވުރެ) ތިމަން މާމޮޅެވެ. އޭނާއީ، ދައްކާ ވާހަކަ ބަޔާން ކޮށްދިނުމާ ގާތްވެސް ނުކުރެވޭ މީހެކެވެ.","",""],["","","","فلولا ألقي عليه أسورة من ذهب أو جاء معه الملائكة مقترنين","ފަހެ، އޭނާގެ މައްޗަށް ރަނުގެ އުޅާތަކެއް ބާވައިނުލެއްވީ ކީއްވެގެން ހެއްޔެވެ؟ ނުވަތަ އޭނާއާއެކުގައި އެހީތެރިވާނެ މަލާއިކަތުން ވަޑައިނުގަތީ ކީއްވެގެން ހެއްޔެވެ؟","",""],["","","","فاستخف قومه فأطاعوه إنهم كانوا قوما فاسقين","ފަހެ، އޭނާ (އެބަހީ: ފިރްޢައުނު) އޭނާގެ ގައުމުގެމީހުން ހައްލައިލިއެވެ. ދެން އެއުރެން އޭނާޔަށް ކިޔަމަންވޫއެވެ. ހަމަކަށަވަރުން، އެއުރެންވީ، ފާސިގު ވެގެންވާ ބަޔަކު ކަމުގައެވެ.","",""],["","","","فلما آسفونا انتقمنا منهم فأغرقناهم أجمعين","ފަހެ، ތިމަންރަސްކަލާނގެ ކޯފާވެވޮޑިގެންވާގޮތަށް، އެއުރެން ކަންތައް ކުރިހިނދު، ތިމަންރަސްކަލާނގެ އެއުރެންގެކިބައިން ބަދަލުހިއްޕެވީމެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ އެއުރެން އެންމެން ޣަރަގުކުރެއްވީމެވެ.","",""],["","","","فجعلناهم سلفا ومثلا للآخرين","ފަހެ، (ކާފިރުވި) އެހެންމީހުންނަށް އިބްރަތެއް ކަމުގައްޔާއި، މިސާލެއް ކަމުގައި ތިމަންރަސްކަލާނގެ އެއުރެން ލެއްވީމެވެ.","",""],["","","","ولما ضرب ابن مريم مثلا إذا قومك منه يصدون","މަރިޔަމްގެފާނުގެ ދަރިކަލުންގެ ވާހަކަ މިސާލެއްގެ ގޮތުގައި ކިޔައިދެއްވިހިނދު، އެހާރުން އެކަންތަކާމެދު ކަލޭގެފާނުގެ ގައުމުގެމީހުން މަލާމާތްކޮށް ހަޅޭލަވަތެވެ.","",""],["","","","وقالوا أآلهتنا خير أم هو ما ضربوه لك إلا جدلا بل هم قوم خصمون","އަދި އެއުރެން ބުނޫއެވެ. ރަނގަޅީ، ތިމަންމެންގެ އިލާހު ންތައް ހެއްޔެވެ؟ ނުވަތަ އެކަލޭގެފާނު ހެއްޔެވެ؟ ކަލޭގެފާނާ ޖަދަލުކުރުމަށް މެނުވީ އެއުރެން އެ މިސާލު ނުޖަހަތެވެ. އަދި ކިއެއްތަ! އެއުރެންނީ ހަމަދެކޮޅުވެރިކަން ބޮޑު ބަޔެކެވެ.","",""],["","","","إن هو إلا عبد أنعمنا عليه وجعلناه مثلا لبني إسرائيل","ތިމަންރަސްކަލާނގެ، އެކަލޭގެފާނަށް ނިއުމަތް ދެއްވި އަޅަކުކަމުގައި މެނުވީ އެކަލޭގެފާނު ނުވެތެވެ. އަދި އިސްރާއީލުގެދަރިންނަށް އިބްރަތެއް ކަމުގައި އެކަލޭގެފާނު ލެއްވީމެވެ.","",""],["","","","ولو نشاء لجعلنا منكم ملائكة في الأرض يخلفون","އަދި ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާނަމަ، ތިޔަބައިމީހުންގެ ބަދަލުގައި ތިޔަބައިމީހުންގެ ފަހަށް، ބިމުގައި މަލާއިކަތުން ލައްވައިފީމުހެވެ.","",""],["","","","وإنه لعلم للساعة فلا تمترن بها واتبعون هذا صراط مستقيم","އަދި ހަމަކަށަވަރުން، އެކަލޭގެފާނީ، ގިޔާމަތް ވުމުގެ ވަގުތަށް ހުރި އަލާމަތެކެވެ. ފަހެ، ތިޔަބައިމީހުން އެދުވަހާމެދު ޝައްކު ނުކުރާހުށިކަމެވެ! އަދި ތިޔަބައިމީހުން ތިމަންރަސްކަލާނގެ މަގަށް ތަބާ ވާށެވެ! މިއީ ސީދާވެގެންވާ ތެދުމަގެވެ.","",""],["","","","ولا يصدنكم الشيطان إنه لكم عدو مبين","އަދި ޝައިތާނާ ތިޔަބައިމީހުން (ތެދުމަގުން) އެއްކިބާކުރިޔަ ނުދޭހުށިކަމެވެ! ހަމަކަށަވަރުން، އެކަލޭގެއީ، ތިޔަބައިމީހުންނަށްހުރި ފާޅުވެގެންވާ އަދާވަތް ތެރިޔެކެވެ.","",""],["","","","ولما جاء عيسى بالبينات قال قد جئتكم بالحكمة ولأبين لكم بعض الذي تختلفون فيه فاتقوا الله وأطيعون","އަދި ޢީސާގެފާނު، ފާޅުވެގެންވާ ހެކިތަކާއިގެން ވަޑައިގެންނެވިހިނދު އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ގާތަށް ތިމަންކަލޭގެފާނު މިވަޑައިގަތީ، ހިކުމަތާއިގެންނެވެ. އަދި ތިޔަބައިމީހުން އެކަންތަކާމެދު ޚިލާފުވާ ބައެއް ކަންތައް ތިޔަބައިމީހުންނަށް ބަޔާންކޮށް ދެއްވުމަށްޓަކައެވެ. ފަހެ، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ތިމަންކަލޭގެފާނަށް ތިޔަބައިމީހުން ކިޔަމަންވާށެވެ!","",""],["","","","إن الله هو ربي وربكم فاعبدوه هذا صراط مستقيم","ހަމަކަށަވަރުން، ﷲއެއީ، ތިމަންގެ ވެރިރަސްކަލާނގެއެވެ. އަދި ތިޔަބައިމީހުންގެވެސް ވެރިރަސްކަލާނގެއެވެ. ފަހެ، ތިޔަބައިމީހުން އެކަލާނގެއަށް އަޅުކަން ކުރާށެވެ! މިއީ ސީދާވެގެންވާ ތެދުމަގެވެ.","",""],["","","","فاختلف الأحزاب من بينهم فويل للذين ظلموا من عذاب يوم أليم","ފަހެ، އެއުރެންގެ މެދުގައި (އެބަހީ: ނަސާރާ އިންގެ މެދުގައި) އެކި ޖަމާއަތްތައް (އެކަލޭގެފާނާމެދު) ދެބަސްވޫއެވެ. ފަހެ، އަނިޔާވެރިވީ މީހުންނަށް ވޭންދެނިވި އަޒާބުގެދުވަހު ހަލާކާއި ގެއްލުން ހުށްޓެވެ.","",""],["","","","هل ينظرون إلا الساعة أن تأتيهم بغتة وهم لا يشعرون","އެއުރެންނަށް ނޭނގިތިއްބައި ކުއްލިޔަކަށް ގިޔާމަތް ވުމުގެ ވަގުތު އަތުވެދާނެކަމަށް މެނުވީ، އެއުރެން އިންތިޒާރެއް ނުކުރެތެވެ.","",""],["","","","الأخلاء يومئذ بعضهم لبعض عدو إلا المتقين","އެކުވެރިން އެދުވަހުން އެއްބަޔަކު އަނެއްބަޔަކަށް ވާހުށީ ދުޝްމަނުން ކަމުގައެވެ. ތަގުވާވެރިން މެނުވީއެވެ.","",""],["","","","يا عباد لا خوف عليكم اليوم ولا أنتم تحزنون","އޭ ތިމަންރަސްކަލާނގެ އަޅުތަކުންނޭވެ! ތިޔަބައިމީހުންގެ މައްޗަކަށް މިއަދު އެއްވެސް ބިރެއް ނެތެވެ. އަދި ހިތާމަކުރާނެ ބަޔަކުކަމުގައިވެސް ތިޔަބައިމީހުން ނުވަމުއެވެ.","",""],["","","","الذين آمنوا بآياتنا وكانوا مسلمين","އެއުރެންނީ، ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް އީމާންވެ، މުސްލިމުން ކަމުގައިވީ މީހުންނެވެ.","",""],["","","","ادخلوا الجنة أنتم وأزواجكم تحبرون","އުފާވެރިކަމުން ފުރިގެންވާ ޙާލު، ތިޔަބައިމީހުންނާއި، ތިޔަބައިމީހުންގެ އަނބިން ސުވަރުގެ ވަންނާށެވެ!","",""],["","","","يطاف عليهم بصحاف من ذهب وأكواب وفيها ما تشتهيه الأنفس وتلذ الأعين وأنتم فيها خالدون","އެއުރެންގެ ގާތުގައި ރަނުގެ ކަންވާރުތަކާއި، ތަށިތަކާއިގެން ބުރުޖެހޭނެތެވެ. އަދި އެތާނގައި ހިތްއެދޭ، އަދި ލޯތަކަށް އަރާމު ލިބިދޭ ހުރިހާ ތަކެތި ވެއެވެ. އަދި ތިޔަބައިމީހުން އެތާނގައި ދެމިތިބޭނެތެވެ.","",""],["","","","وتلك الجنة التي أورثتموها بما كنتم تعملون","އަދި އެއީ ތިޔަބައިމީހުން ކޮށްއުޅުނު ހެޔޮ ޢަމަލުތަކުގެ ސަބަބުން ތިޔަބައިމީހުންނަށް މިލްކުކޮށްދެއްވި ސުވަރުގެއެވެ.","",""],["","","","لكم فيها فاكهة كثيرة منها تأكلون","އެތާނގައި ތިޔަބައިމީހުން، އެއިން ކައިއުޅުމަށް ގިނަގުނަ މޭވާތައް ވެއެވެ.","",""],["","","","إن المجرمين في عذاب جهنم خالدون","ހަމަކަށަވަރުން، ކުށްވެރިން ނަރަކައިގެ އަޒާބުގައި ދެމިތިބޭނެތެވެ.","",""],["","","","لا يفتر عنهم وهم فيه مبلسون","އެއުރެންގެ ކިބައިން އެ އަޒާބު ލުޔެއް ނުކުރައްވާނެތެވެ. އަދި އެއުރެން އެކަމުގައި ތިބޭހުށީ އުންމީދު ކެނޑިފައެވެ.","",""],["","","","وما ظلمناهم ولكن كانوا هم الظالمين","އަދި ތިމަންރަސްކަލާނގެ އެއުރެންނަކަށް އަނިޔާއެއް ނުކުރައްވަމެވެ. އެހެނެއްކަމަކު (ފާފަކުރުމުގެ ސަބަބުން) އަނިޔާވެރިންކަމުގައިވީ، ހަމަ އެއުރެންނެވެ.","",""],["","","","ونادوا يا مالك ليقض علينا ربك قال إنكم ماكثون","އެއުރެން ގޮވާނެތެވެ. އޭ މާލިކުގެފާނެވެ! ތިމަންމެން މަރުގެންނެވުމަށް ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ދަންނަވައިދެއްވާށެވެ! އެކަލޭގެފާނު ވިދާޅުވާނެތެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނީ (އަޒާބުގައި) ދެމިތިބޭނޭ ބަޔެކެވެ.","",""],["","","","لقد جئناكم بالحق ولكن أكثركم للحق كارهون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، ތިޔަބައިމީހުންނަށް ހައްގު ދީންގެނެސް ދެއްވީމެވެ. އެހެނެއްކަމަކު، ތިޔަބައިމީހުންކުރެ ގިނަމީހުންވަނީ ހައްގު ދީނަށް ނުރުހޭ ބަޔަކު ކަމުގައެވެ.","",""],["","","","أم أبرموا أمرا فإنا مبرمون","ނުވަތަ އެއުރެން (ކަލޭގެފާނު ނެތިކޮށްލުމަށް) ކަމެއް ރޭވީހެއްޔެވެ؟ ފަހެ، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ (އެއަށްވުރެ މޮޅަށް) ރާއްވަވާ ހުށީމެވެ.","",""],["","","","أم يحسبون أنا لا نسمع سرهم ونجواهم بلى ورسلنا لديهم يكتبون","ނުވަތަ އެއުރެން ހީކުރަނީ، އެއުރެންގެ ސިއްރު ވާހަކަތަކާއި، އެއުރެންގެ ސިއްރު ސައްލާތައް ތިމަންރަސްކަލާނގެ އައްސަވާވޮޑިގެން ނުވާކަމަށްހެއްޔެވެ؟ އެހެންނަކުން ނޫނެވެ. (އައްސަވާވޮޑިގެންވަމެވެ.) އަދި އެއުރެންގެގާތަށް، ތިމަންރަސްކަލާނގެ ފޮނުއްވާފައިވާ މަލާއިކަތުން އެކަންތައް ލިޔުއްވަތެވެ.","",""],["","","","قل إن كان للرحمن ولد فأنا أول العابدين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ރަޙްމާންވަންތަ ރަސްކަލާނގެއަށް ދަރިކަލަކުވާނަމަ (އެ ދަރިކަލަކަށް) އެންމެފުރަތަމަ އަޅުކަންކުރާނެ މީހަކީ ތިމަންކަލޭގެފާނެވެ.","",""],["","","","سبحان رب السماوات والأرض رب العرش عما يصفون","އެއުރެން ސިފަކުރާ ކަންތަކުން އުޑުތަކާއި، ބިމުގެވެރި، ޢަރްޝުގެ ވެރިރަސްކަލާނގެ ހުސްތާހިރު ވެވޮޑިގެންވެއެވެ.","",""],["","","","فذرهم يخوضوا ويلعبوا حتى يلاقوا يومهم الذي يوعدون","ފަހެ، އެއުރެންނަށް ވައުދުކުރައްވާ ދުވަހާ އެއުރެން ބައްދަލުވެއްޖައުމަށް ދާނދެން، ބާތިލު ވާހަކަތައް ދައްކައި، ކުޅިވަރުކުޅެން ކަލޭގެފާނު އެއުރެން ދޫކޮށްލައްވާށެވެ!","",""],["","","","وهو الذي في السماء إله وفي الأرض إله وهو الحكيم العليم","އުޑުގައިވެސް އިލާހަކީ އެކަލާނގެއެވެ. އަދި ބިމުގައިވެސް އިލާހަކީ އެކަލާނގެއެވެ. އެކަލާނގެއީ، ޙަކީމްވަންތަ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وتبارك الذي له ملك السماوات والأرض وما بينهما وعنده علم الساعة وإليه ترجعون","އަދި އުޑުތަކާއި، ބިމާއި، އެދެމެދުގައި ވާހާތަކެއްޗެއް މަލަކަ ވެގެންވާ ރަސްކަލާނގެ މަތިވެރިވެވޮޑިގެންފިއެވެ. އަދި ގިޔާމަތް ވުމުގެ ވަގުތު ދެނެވޮޑިގަތުންވަނީ، އެކަލާނގެ ހަޒުރަތު ގައެވެ. އަދި ތިޔަބައިމީހުން އެނބުރި ރުޖޫއަކުރައްވާހުށީ އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","ولا يملك الذين يدعون من دونه الشفاعة إلا من شهد بالحق وهم يعلمون","އެކަލާނގެ ފިޔަވައި އެއުރެން އަޅުކަންކުރާ ތަކެއްޗަށް ޝަފާއަތް ތެރިކަމެއް މަލަކަ ވެގެނެއް ނުވެތެވެ. އެއުރެން ދެނެތިބެ، ހައްގަށް ހެކިދިން މީހުން މެނުވީއެވެ.","",""],["","","","ولئن سألتهم من خلقهم ليقولن الله فأنى يؤفكون","ހަމަކަށަވަރުން، އެއުރެން ހެއްދެވީ ކާކުތޯ، އެއުރެންނާ ކަލޭގެފާނު ސުވާލުކުރައްވައިފިނަމަ، އެއުރެން ބުނާނެކަން ކަށަވަރެވެ. ﷲއެވެ. ފަހެ، އެއުރެން ހައްގުން އެއްކިބާވަނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","وقيله يا رب إن هؤلاء قوم لا يؤمنون","އަދި އެކަލޭގެފާނު ވިދާޅުވި ވިދާޅުވުން، އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، މިބައިމީހުންނީ އީމާން ނުވާނެ ބަޔެކެވެ.","",""],["","","","فاصفح عنهم وقل سلام فسوف يعلمون","ފަހެ، ކަލޭގެފާނު އެއުރެންނާ އެއްކިބާވެ ވަޑައިގަންނަވާށެވެ! އަދި ވިދާޅުވާށެވެ! ސަލާމެވެ! ފަހެ، ނިކަންހުރެ އެއުރެންނަށް (އެއުރެން ދޮގުކުރިކަމުގެ ނަތީޖާ) އެނގޭނެތެވެ.","",""],["","","","بسم الله الرحمن الرحيم حم","ح م (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","والكتاب المبين","ބަޔާން ވެގެންވާ ފޮތް ގަންދެއްވައި ވަހީކުރައްވަމެވެ.","",""],["","","","إنا أنزلناه في ليلة مباركة إنا كنا منذرين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެފޮތް (އެބަހީ: ގުރްއާން) ބާވައިލެއްވީ ބަރަކާތްތެރިވެގެންވާ ރެޔެއްގައެވެ. ހަމަކަށަވަރުން، އިންޒާރުކުރައްވާ ކަލަކު ކަމުގައި ތިމަންރަސްކަލާނގެ ވޮޑިގެންވަމެވެ.","",""],["","","","فيها يفرق كل أمر حكيم","އެ ރޭ، ކަނޑައެޅިގެންވާ ކޮންމެކަމެއް ބަޔާންކުރައްވަތެވެ.","",""],["","","","أمرا من عندنا إنا كنا مرسلين","(އެއީ) ތިމަންރަސްކަލާނގެ ހަޒުރަތުން އައި އަމުރެއް ކަމުގައެވެ. ހަމަކަށަވަރުން، ރަސޫލުން ފޮނުއްވާ ކަލަކު ކަމުގައި ތިމަންރަސްކަލާނގެ ވޮޑިގެންވަމެވެ.","",""],["","","","رحمة من ربك إنه هو السميع العليم","(އެއީ) ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ފޮނުއްވާ ރަހުމަތެއް ކަމުގައެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","رب السماوات والأرض وما بينهما إن كنتم موقنين","(އެއީ) އުޑުތަކާއި، ބިމާއި، އެދެމެދުގައިވާހާ ތަކެއްޗެއްގެ ވެރިރަސްކަލާނގެއެވެ. ތިޔަބައިމީހުން ޔަގީންކުރާ ބަޔަކު ކަމުގައިވާނަމައެވެ.","",""],["","","","لا إله إلا هو يحيي ويميت ربكم ورب آبائكم الأولين","އެކަލާނގެ މެނުވީ އެހެން އިލާހަކުނުވެއެވެ. ދިރުއްވަނީވެސް، އަދި މަރުގަންނަވަނީވެސް، ހަމަ އެކަލާނގެއެވެ. އެއީ ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއެވެ. އަދި ތިޔަބައިމީހުންގެ އިސްވެދިޔަ ކާބަފައިންގެވެސް ވެރިރަސްކަލާނގެއެވެ.","",""],["","","","بل هم في شك يلعبون","އަދި ކިއެއްތަ! އެއުރެން ޝައްކުކަމެއްގައި ކުޅެކުޅެ ތިބެތެވެ.","",""],["","","","فارتقب يوم تأتي السماء بدخان مبين","ފަހެ، ފާޅުވެގެންވާ ދުމަކާއިގެން އުޑު އަންނަނިވި ދުވަހަށް އިންތިޒާރުކުރާށެވެ!","",""],["","","","يغشى الناس هذا عذاب أليم","އެ، ދުން މީސްތަކުން ފޮރުވައިލާނެތެވެ. (އަދި އެއުރެން ބުނާނެތެވެ.) މިއީ ވޭންދެނިވި އަޒާބެކެވެ.","",""],["","","","ربنا اكشف عنا العذاب إنا مؤمنون","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެންގެ ކިބައިން އަޒާބު ފިއްލަވާނދޭވެ! ހަމަކަށަވަރުން، އަޅަމެން އީމާން ވާހުށީމުއެވެ.","",""],["","","","أنى لهم الذكرى وقد جاءهم رسول مبين","އެއުރެން ނަސޭހަތް ލިބިގަންނާނީ ކޮންފަދައަކުން ހެއްޔެވެ؟ އެއުރެންގެ ގާތަށް ބަޔާންވެގެންވާ ރަސޫލަކު ވަނީ ވަޑައިގެންފައެވެ.","",""],["","","","ثم تولوا عنه وقالوا معلم مجنون","ދެން އެއުރެން އެކަލޭގެފާނަށް ފުރަގަސްދިނޫއެވެ. އަދި އެއުރެން ބުނޫއެވެ. އެކަލޭގެފާނީ، އުނގަންނައިދެވިފައިވާ މޮޔައެކެވެ.","",""],["","","","إنا كاشفو العذاب قليلا إنكم عائدون","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކުޑަހިނދުކޮޅަކަށް އަޒާބު ފިއްލަވާހުށީމެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނީ، (ކާފިރުކަމަށް) އެނބުރި އަންނާނޭ ބަޔެކެވެ.","",""],["","","","يوم نبطش البطشة الكبرى إنا منتقمون","ބޮޑުވެގެންވާ، ގަދަފަދަ ހިއްޕެވުމަކުން ތިމަންރަސްކަލާނގެ ހިއްޕަވާ ދުވަސް ހަނދުމަކުރާށެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ (އެއުރެންގެ ކިބައިން އެދުވަހުން) ބަދަލުހިއްޕަވާހުށީމެވެ.","",""],["","","","ولقد فتنا قبلهم قوم فرعون وجاءهم رسول كريم","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެންގެ ކުރިން ފިރްޢައުނުގެ ގައުމުގެމީހުން އިމްތިހާނުކުރެއްވީމެވެ. އަދި އެއުރެންގެގާތަށް މާތްވެގެންވާ ރަސޫލަކު ވަޑައިގަތެވެ.","",""],["","","","أن أدوا إلي عباد الله إني لكم رسول أمين","(ވިދާޅުވަމުންނެވެ.) އޭ ﷲގެ އަޅުތަކުންނޭވެ! ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނަށް ތަބާ ވާށެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނީ، ތިޔަބައިމީހުންގެ ގާތަށް ފޮނުއްވެވި އަމާނާތްތެރި ރަސޫލަކީމެވެ.","",""],["","","","وأن لا تعلوا على الله إني آتيكم بسلطان مبين","އަދި (ވިދާޅުވަމުންނެވެ.) ތިޔަބައިމީހުން ﷲގެ މައްޗަށް ބޮޑާވެނުގަންނަހުށިކަމެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނު ތިޔަބައިމީހުންގެ ގާތަށް ބަޔާންވެގެންވާ ދަލީލެއް ގެންނަވާހުށީމެވެ.","",""],["","","","وإني عذت بربي وربكم أن ترجمون","ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނު ރަޖަމްކުރުމުން ސަލާމަތްކުރެއްވުންއެދި ތިމަންގެ ވެރި، އަދި ތިޔަބައިމީހުންގެވެސް ވެރިރަސްކަލާނގެ ހަޒުރަތުން، ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނު ރައްކާތެރިކަން ލިބިގަންނަމެވެ.","",""],["","","","وإن لم تؤمنوا لي فاعتزلون","އަދި ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނަށް އީމާން ނުވިނަމަ، ފަހެ، ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނާ ވަކިވާށެވެ!","",""],["","","","فدعا ربه أن هؤلاء قوم مجرمون","ފަހެ، އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް އެކަލޭގެފާނު ދުއާކުރައްވައި ވިދާޅުވިއެވެ. މިބައިމީހުންނީ ކުށްވެރިވެގެންވާ ބަޔެކެވެ.","",""],["","","","فأسر بعبادي ليلا إنكم متبعون","(އެކަލާނގެ ވަހީކުރެއްވިއެވެ.) ފަހެ، ތިމަންރަސްކަލާނގެ އަޅުތަކުންނާއިގެން ރޭގަނޑެއްގައި ކަލޭގެފާނު ހިންގަވައި ވަޑައިގަންނަވާށެވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ފަހަތުން (ފިރްޢައުނާއި، އޭނާގެ ލަޝްކަރު) އަންނާނެތެވެ.","",""],["","","","واترك البحر رهوا إنهم جند مغرقون","އަދި ކަނޑު އެއޮތްގޮތަށް (އެބަހީ: އެ ކަނޑު އިރުއްވެވިގޮތަށް) ހިމޭންކަމާއެކު ދޫކޮށްލައްވާށެވެ. ހަމަކަށަވަރުން، އެއުރެންނީ ޣަރަގުކުރައްވާނޭ ލަޝްކަރެކެވެ.","",""],["","","","كم تركوا من جنات وعيون","ކިތައްކިތައް ބަގީޗާއާއި، ކިތައްކިތައް އާރު، އެއުރެން ދޫކުރިހެއްޔެވެ؟","",""],["","","","وزروع ومقام كريم","އަދި ދަނޑުތަކާއި، ރީތި ގޭގެވެސްމެއެވެ.","",""],["","","","ونعمة كانوا فيها فاكهين","އަދި އުފަލުގައި އެއުރެން ދިރިއުޅުނުކަމުގައިވި ނިއުމަތްގެ ތަނަވަސް ދިރިއުޅުމެވެ.","",""],["","","","كذلك وأورثناها قوما آخرين","(ކަންތައްހުރީ) އެފަދައިންނެވެ. އަދި ތިމަންރަސްކަލާނގެ އެތަކެތި އެހެންބަޔަކަށް ވާރުތަކުރެއްވީމެވެ.","",""],["","","","فما بكت عليهم السماء والأرض وما كانوا منظرين","ފަހެ، އެއުރެންގެ މައްޗަކަށް އުޑެއްވެސް، އަދި ބިމެއްވެސް (ހިތާމަކޮށް) ނުރޮއެވެ. އަދި އެއުރެންނީ މުހުލަތް ދެއްވާފައިވާ ބަޔަކުކަމުގައި ނުވެތެވެ.","",""],["","","","ولقد نجينا بني إسرائيل من العذاب المهين","ހަމަކަށަވަރުން، ނިކަމެތިކަންދެނިވި އަޒާބުން، ތިމަންރަސްކަލާނގެ އިސްރާއީލުގެދަރިން މިންޖުކުރެއްވީމެވެ.","",""],["","","","من فرعون إنه كان عاليا من المسرفين","(އެއީ) ފިރްޢައުނުގެ ކިބައިންނެވެ. ހަމަކަށަވަރުން (ފުރެދުމުގައި) ހައްދުފަހަނަޅައިފައިވާ މީހުންގެ ތެރެއިން ކިބުރުވެރިޔަކު ކަމުގައި އޭނާ ވިއެވެ.","",""],["","","","ولقد اخترناهم على علم على العالمين","އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގަތުމުގެމަތިން އާލަމްތަކުގެ މައްޗަށް އެއުރެން ޚިޔާރުކުރެއްވީމެވެ.","",""],["","","","وآتيناهم من الآيات ما فيه بلاء مبين","އަދި ބަޔާންވެގެންވާ އިމްތިހާނެއް އޭގައި އެކުލެވިގެންވާ ހެކިތައް ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްވީމެވެ.","",""],["","","","إن هؤلاء ليقولون","ހަމަކަށަވަރުން، މިބައިމީހުން ބުނާކަން ކަށަވަރެވެ.","",""],["","","","إن هي إلا موتتنا الأولى وما نحن بمنشرين","އެއީ ތިމަންމެންގެ ފުރަތަމަ މަރުކަމުގައިމެނުވީ ނުވެތެވެ. އަދި ތިމަންމެންނީ، އަލުން ދިރުއްވައި ފޮނުއްވާނޭ ބަޔަކުކަމުގައި ނުވަމުއެވެ.","",""],["","","","فأتوا بآبائنا إن كنتم صادقين","ފަހެ، ތިޔަބައިމީހުން ތެދުވެރިންކަމުގައިވަނީނަމަ، ތިމަންމެންގެ ކާބަފައިން (ދިރުވައި) ގެނެސްބަލާށެވެ!","",""],["","","","أهم خير أم قوم تبع والذين من قبلهم أهلكناهم إنهم كانوا مجرمين","ރަނގަޅީ އެއުރެން ހެއްޔެވެ؟ ނުވަތަ ތުއްބަޢުގެ ގައުމުގެމީހުންނާއި، އެއުރެންގެ ކުރިންއުޅުނު މީހުން ހެއްޔެވެ؟ ތިމަންރަސްކަލާނގެ އެއުރެން ހަލާކުކުރެއްވީމެވެ. ހަމަކަށަވަރުން، އެއުރެންވީ ކުށްވެރިން ކަމުގައެވެ.","",""],["","","","وما خلقنا السماوات والأرض وما بينهما لاعبين","ތިމަންރަސްކަލާނގެ، އުޑުތަކާއި، ބިމާއި، އެދެމެދުގައިވާހައި ތަކެތި، ކުޅިވަރެއްގެ ގޮތުގައި ނަހައްދަވަމެވެ.","",""],["","","","ما خلقناهما إلا بالحق ولكن أكثرهم لا يعلمون","ހައްގު ގޮތުގައި މެނުވީ ތިމަންރަސްކަލާނގެ، އެ ދެތަނެއް ނަހައްދަވަމެވެ. އެހެނެއްކަމަކު، އެއުރެންކުރެ ގިނަމީހުންނަކަށް (އެކަމެއް) ނޭނގެތެވެ.","",""],["","","","إن يوم الفصل ميقاتهم أجمعين","ހަމަކަށަވަރުން، ނިޔާކުރެއްވުމުގެ ދުވަހަކީ، އެއުރެން އެންމެންނަށް ކަނޑައަޅުއްވާފައިވާ މީޢާދެވެ.","",""],["","","","يوم لا يغني مولى عن مولى شيئا ولا هم ينصرون","(އެއީ) އެއްވެސް އެހީތެރިޔަކަށް، އަނެއް އެހީތެރިޔެއްގެ ކިބައިން އެއްވެސްކަމެއް ފުއްދައިނުދެވޭނޭ ދުވަހެވެ. އަދި ނަސްރު ލިބޭނޭ ބަޔަކުކަމުގައިވެސް އެއުރެން ނުވެތެވެ.","",""],["","","","إلا من رحم الله إنه هو العزيز الرحيم","ﷲ ރަހުމަތް ލެއްވި މީހުން މެނުވީއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ޢަޒީޒުވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","إن شجرت الزقوم","ހަމަކަށަވަރުން، ޒައްގޫމު ގަހަކީ (ނަރަކައިގައި) ފާފަވެރިޔާގެ ކާނާއެވެ.","",""],["","","","طعام الأثيم","ހަމަކަށަވަރުން، ޒައްގޫމު ގަހަކީ (ނަރަކައިގައި) ފާފަވެރިޔާގެ ކާނާއެވެ.","",""],["","","","كالمهل يغلي في البطون","ތެޔޮކުނޑިފަދައިން ބަނޑުތަކުގައި އެ ކެކޭނެތެވެ.","",""],["","","","كغلي الحميم","ކެކިކެކިހުންނަ ފެން ކެކޭފަދައިންނެވެ.","",""],["","","","خذوه فاعتلوه إلى سواء الجحيم","(ޒަބާނިއްޔަ މަލާއިކަތުންނަށް އަންގަވާނެތެވެ.) ގަދަފަދަކަމާއެކު އެމީހާ ނަރަކައިގެ މެދަށް ދަމައި ގެންދާށެވެ!","",""],["","","","ثم صبوا فوق رأسه من عذاب الحميم","ދެން އޭނާގެ ބޮލަށް، ކެކި އުތުރިއަރާ ހޫނުފެނުގެ އަޒާބު އޮއްސާށެވެ!","",""],["","","","ذق إنك أنت العزيز الكريم","(އަދި އޭނާޔަށް އަންގަވާނެތެވެ.) ކަލޭ (އަޒާބުގެ) ރަހަ ދެކޭށެވެ! ކަލެޔަކީ ހަމަ، ބާރުގަދަ މާތް މީޙަކީމުއެވެ.","",""],["","","","إن هذا ما كنتم به تمترون","ހަމަކަށަވަރުން، މިއީ ތިޔަބައިމީހުން އެކަންތަކާމެދު ޝައްކު ކޮށްއުޅުނު ކަންތަކެވެ.","",""],["","","","إن المتقين في مقام أمين","ހަމަކަށަވަރުން، ތަގުވާވެރިން ތިބޭހުށީ އަމާންކަން ލިބިގެންވާ ތަނެއްގައެވެ.","",""],["","","","في جنات وعيون","ސުވަރުގެތަކާއި، ފެންއާރުތަކުގެ ނިއުމަތް ގައެވެ.","",""],["","","","يلبسون من سندس وإستبرق متقابلين","އެއުރެން ލައިއުޅޭހުށީ، ސުންދުސާއި، އިސްތަބްރަގު ފޭރާމެވެ. ތިބޭހުށީ އެއްބަޔަކު އަނެއްބަޔަކާ ކުރިމަތިލައިގެންނެވެ.","",""],["","","","كذلك وزوجناهم بحور عين","(ކަންހުރީ) އެފަދައިންނެވެ. އަދި ތިމަންރަސްކަލާނގެ އެއުރެން ޙޫރުލްޢީނުންނާ ކާވެނިކޮށްދެއްވާހުށީމެވެ.","",""],["","","","يدعون فيها بكل فاكهة آمنين","އެތާނގައި އަމާންކަންމަތީގައި ތިބޭ ޙާލު، ހުރިހާ ބާވަތެއްގެ މޭވާ ގެނައުމަށް އެއުރެން އެދޭނެތެވެ.","",""],["","","","لا يذوقون فيها الموت إلا الموتة الأولى ووقاهم عذاب الجحيم","ފުރަތަމަފަހަރު މަރުވި މަރުވުން ފިޔަވައި، އެތާނގައި އެއުރެން މަރުގެ ރަހައެއް ނުދެކޭނެތެވެ. އަދި ނަރަކައިގެ އަޒާބުން، އެކަލާނގެ އެއުރެން ސަލާމަތްކުރައްވާނެތެވެ.","",""],["","","","فضلا من ربك ذلك هو الفوز العظيم","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައި ފަޟްލު ވަންތަވެރިކަމެއްގެ ގޮތުގައެވެ. ބޮޑުވެގެންވާ ނަސީބު ލިބުމަކީ ހަމައެއީއެވެ.","",""],["","","","فإنما يسرناه بلسانك لعلهم يتذكرون","ފަހެ، ތިމަންރަސްކަލާނގެ، އެފޮތް ކަލޭގެފާނުގެ ބަހުން ފަސޭހަކޮށްދެއްވިކަން ކަށަވަރީ، އެއުރެން ހަނދުމަކުރުމަށްޓަކައެވެ.","",""],["","","","فارتقب إنهم مرتقبون","ފަހެ، ކަލޭގެފާނު ބަލަބަލައި ހުންނަވާށެވެ! ހަމަކަށަވަރުން، އެއުރެންވެސް ބަލަބަލައި ތިބޭނެތެވެ.","",""],["","","","بسم الله الرحمن الرحيم حم","ح م (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","تنزيل الكتاب من الله العزيز الحكيم","މިއީ ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ﷲގެ ހަޒުރަތުން ބާވައިލެއްވި ފޮތެވެ.","",""],["","","","إن في السماوات والأرض لآيات للمؤمنين","ހަމަކަށަވަރުން، މުއުމިނުންނަށް އުޑުތަކާއި، ބިމުގައި (ﷲގެ ގުދުރަތް ތެރިކަމުގެ) ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","وفي خلقكم وما يبث من دابة آيات لقوم يوقنون","އަދި ތިޔަބައިމީހުން ހެއްދެވުމުގައްޔާއި، އެކަލާނގެ ފަތުރުއްވާފައިވާ (އެންމެހާ) ދިރޭތަކެތީގައި ޔަގީންކުރާ ބަޔަކަށް ހެކިތަކެއްވެއެވެ.","",""],["","","","واختلاف الليل والنهار وما أنزل الله من السماء من رزق فأحيا به الأرض بعد موتها وتصريف الرياح آيات لقوم يعقلون","އަދި ރޭދުވާ ތަފާތުވުމުގައްޔާއި، ބިން މަރުވުމަށްފަހު، ﷲ، އުޑުން ވެއްސެވި ރިޒްގުން (އެބަހީ: ވާރޭފެނުން) އެ ބިން ދިރުއްވިކަމާއި، ވައިރޯޅި (އެކިފަރާތްފަރާތަށް) ހިންގެވުމުގައި، ވިސްނާބަޔަކަށް ހެކިތަކެއްވެއެވެ.","",""],["","","","تلك آيات الله نتلوها عليك بالحق فبأي حديث بعد الله وآياته يؤمنون","އެއީ ﷲގެ އާޔަތް ތަކެވެ. ހައްގު (ތެދު) ގޮތުގައި ކަލޭގެފާނަށް ތިމަންރަސްކަލާނގެ އާޔަތްތައް ކިޔައިދެއްވަމެވެ. ފަހެ، ﷲގެ ފޮތާއި، އެކަލާނގެ އާޔަތް ތަކަށްފަހުގައި، އެއުރެން އީމާން ވާނީ ކޮންވާހަކަޔަކަށް ހެއްޔެވެ؟","",""],["","","","ويل لكل أفاك أثيم","ދޮގުހަދާ، ފާފަވެރި ކޮންމެ މީހަކަށް ހަލާކާއި ގެއްލުން ހުށްޓެވެ.","",""],["","","","يسمع آيات الله تتلى عليه ثم يصر مستكبرا كأن لم يسمعها فبشره بعذاب أليم","ﷲގެ އާޔަތްތައް އެމީހަކަށް ކިޔައިދެވޭ އަޑުއަހައިމެ، ދެން އޭގެ އަޑު ނާހާފަދައިން ބޮޑާވެގަތުމާއެކު (ކާފިރު ކަންމަތީ ދެމިހުރުމަށް) ގަދަހަދާ މީހާޔަށް ވޭންދެނިވި އަޒާބު ހުރިކަމުގެ ޚަބަރު، ކަލޭގެފާނު ދެއްވާށެވެ!","",""],["","","","وإذا علم من آياتنا شيئا اتخذها هزوا أولئك لهم عذاب مهين","އަދި ތިމަންރަސްކަލާނގެ އާޔަތް ތަކުން އެއްޗެއް އޭނާއަށް އެނގިއްޖެނަމަ، އެއެއްޗެއް ފުރައްސާރައަކަށް ހަދައިގެން އުޅެތެވެ. އެއުރެންނަށް އިހާނަތްތެރިކަންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["","","","من ورائهم جهنم ولا يغني عنهم ما كسبوا شيئا ولا ما اتخذوا من دون الله أولياء ولهم عذاب عظيم","އެއުރެންގެ ފަހަތުގައިވަނީ ނަރަކަޔެވެ. އަދި އެއުރެން ހޯދި އެއްޗަކުން ނުވަތަ ﷲ ފިޔަވައި އެއުރެން އެހީތެރިން ކަމުގައި ހިފިތަކެއްޗަކުން، އެއުރެންނަކަށް އެއްވެސްކަމެއް ފުއްދައެއް ނުދޭނެތެވެ. އަދި އެއުރެންނަށް ބޮޑުވެގެންވާ އަޒާބު ހުށްޓެވެ.","",""],["","","","هذا هدى والذين كفروا بآيات ربهم لهم عذاب من رجز أليم","މިއީ (އެބަހީ: މި ގުރްއާނަކީ) ތެދުމަގެކެވެ. އަދި އެއުރެންގެ ވެރިރަސްކަލާނގެ އާޔަތްތަކަށް ކާފިރުވި މީހުންނަށް ވޭންދެނިވި، އެންމެގަދަ އަޒާބުން އަޒާބު ހުށްޓެވެ.","",""],["","","","الله الذي سخر لكم البحر لتجري الفلك فيه بأمره ولتبتغوا من فضله ولعلكم تشكرون","ﷲއީ، ތިޔަބައިމީހުންނަށްޓަކައި ކަނޑު ޚިދުމަތް ތެރިކުރެއްވި ރަސްކަލާނގެއެވެ. (އެއީ) އެކަލާނގެ އަމުރު ފުޅަށް އެތާނގައި އުޅަނދުތައް ދުވުމަށްޓަކައެވެ. އަދި ތިޔަބައިމީހުން އެކަލާނގެ ފަޟްލު ވަންތަކަމުން އެދިގަތުމަށްޓަކައެވެ. އަދި ތިޔަބައިމީހުން ޝުކުރުކުރުމަށްޓަކައެވެ.","",""],["","","","وسخر لكم ما في السماوات وما في الأرض جميعا منه إن في ذلك لآيات لقوم يتفكرون","އަދި އުޑުތަކާއި، ބިމުގައިވާހާ ތަކެއްޗެއް އެކަލާނގެ ތިޔަބައިމީހުންނަށްޓަކައި ޚިދުމަތް ތެރިކޮށްދެއްވިއެވެ. އެހުރިހާ ތަކެއްޗެއްވަނީ، އެކަލާނގެ ހަޒުރަތުންނެވެ. ހަމަކަށަވަރުން، އެކަމުގައި ފިކުރުކުރާ ބަޔަކަށް ހެކިތަކެއްވާކަން ކަށަވަރެވެ.","",""],["","","","قل للذين آمنوا يغفروا للذين لا يرجون أيام الله ليجزي قوما بما كانوا يكسبون","އީމާންވި މީހުންނަށް ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲގެ ދުވަސްތަކަށް (އެބަހީ: އެކަލާނގެ އުގޫބާތަށް) ބިރުނުގަންނަ މީހުންނަށް މާފު (ކޮށް އެއުރެންގެ އުނދަގޫތަކަށް ކެތް) ކުރާހުށިކަމެވެ! (އެއީ) އެއުރެން ހޯދައިއުޅުނު ޢަމަލުތަކުގެ ސަބަބުން އެކަލާނގެ އެއުރެންނަށް ޖަޒާ ދެއްވުމަށްޓަކައެވެ.","",""],["","","","من عمل صالحا فلنفسه ومن أساء فعليها ثم إلى ربكم ترجعون","ސާލިހު ޢަމަލެއް ކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެކަމުގެ ދަރުމަހުރީ، އެމީހާގެ އަމިއްލަ ނަފްސަށެވެ. އަދި ނުބައި ޢަމަލެއް ކޮށްފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެކަމުގެ ހަލާކުހުރީ، ހަމަ އެ ނަފްސުގެ މައްޗަށެވެ. ދެން ތިޔަބައިމީހުން ރުޖޫއަކުރައްވާހުށީ، ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","ولقد آتينا بني إسرائيل الكتاب والحكم والنبوة ورزقناهم من الطيبات وفضلناهم على العالمين","ހަމަކަށަވަރުން، އިސްރާއީލުގެދަރިންނަށް ތިމަންރަސްކަލާނގެ ފޮތާއި، ހިކުމަތާއި، ނަބީކަން ދެއްވީމެވެ. އަދި ރަނގަޅު ތަކެތިން އެއުރެންނަށް ރިޒްގު ދެއްވީމެވެ. އަދި (އެދުވަސްވަރުގެ) އާލަމްތަކުގެ މައްޗަށް އެއުރެން މާތްކުރެއްވީމެވެ.","",""],["","","","وآتيناهم بينات من الأمر فما اختلفوا إلا من بعد ما جاءهم العلم بغيا بينهم إن ربك يقضي بينهم يوم القيامة فيما كانوا فيه يختلفون","އަދި ދީންގެ ކަންތަކާމެދުގައި ބަޔާން ވެގެންވާ ހެކިތަކެއް ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްވީމެވެ. ފަހެ، އެއުރެންނާ ހަމަޔަށް އިލްމު އައުމަށްފަހުގައި މެނުވީ، އެއުރެން ޚިލާފެއް ނުވެތެވެ. (އެއީ) އެއުރެންގެ މެދުގައިވާ ދެކޮޅުވެރިކަމާއި، ހަސަދަވެރިކަމުންނެވެ. ހަމަކަށަވަރުން، އެއުރެން ޚިލާފުވެ އުޅުނު ކަންތަކާމެދު، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ގިޔާމަތް ދުވަހުން އެއުރެންގެ މެދުގައި ނިޔާ ކުރައްވާނެތެވެ.","",""],["","","","ثم جعلناك على شريعة من الأمر فاتبعها ولا تتبع أهواء الذين لا يعلمون","ދެން ތިމަންރަސްކަލާނގެ ދީންގެ ކަންތަކުގައި (ފާޅުވެގެންވާ) ޝަރީޢަތެއްގެ މަތީގައި ކަލޭގެފާނު ލެއްވީމެވެ. ފަހެ، ކަލޭގެފާނު އެޔަށް ތަބާ ވެވަޑައިގަންނަވާށެވެ! އަދި ނުދަންނަ މީހުންގެ އެދުންތަކަށް ކަލޭގެފާނު ތަބާ ވެވަޑައި ނުގަންނަވާށެވެ!","",""],["","","","إنهم لن يغنوا عنك من الله شيئا وإن الظالمين بعضهم أولياء بعض والله ولي المتقين","ހަމަކަށަވަރުން، އެއުރެންނަކަށް ﷲގެ ހަޒުރަތުން ކަލޭގެފާނަކަށް އެއްވެސް ކަމެއް ފުއްދައެއް ނުދެވޭނެތެވެ. އަދި ހަމަކަށަވަރުން، އަނިޔާވެރިންނީ އެއުރެންގެ އެއްބަޔަކު އަނެއްބަޔެއްގެ އެހީތެރިންނެވެ. އަދި ﷲއީ، ތަގުވާވެރިންގެ އެހީތެރިވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","هذا بصائر للناس وهدى ورحمة لقوم يوقنون","މި ގުރްއާނަކީ، މީސްތަކުންނަށްވާ އަލިގަދަ ދަލީލު ތަކެކެވެ. އަދި ޔަގީންކުރާ ބަޔަކަށްވާ ހިދާޔަތަކާއި، ރަހުމަތެކެވެ.","",""],["","","","أم حسب الذين اجترحوا السيئات أن نجعلهم كالذين آمنوا وعملوا الصالحات سواء محياهم ومماتهم ساء ما يحكمون","ނުބައިކަންތައް ކުރިމީހުން، އީމާންވެ ސާލިހު ޢަމަލުތައްކުރި މީހުންނާއެއްފަދަ ކަމުގައި ތިމަންރަސްކަލާނގެ ލައްވާނޭކަމަށް (އަދި) އެއުރެންގެ ދިރިތިބުމާއި، މަރުވުން، ހަމަހަމަވެގެންވާކަމަށް އެއުރެން ހީކުރީހެއްޔެވެ؟ އެއުރެން ކުރާ ހުކުމް ހާދަހާ ނުބައިވެގެންވެއެވެ!","",""],["","","","وخلق الله السماوات والأرض بالحق ولتجزى كل نفس بما كسبت وهم لا يظلمون","ﷲ، އުޑުތަކާއި ބިން ހައްގު ގޮތުގައި ހެއްދެވިއެވެ. (އެއީ) ކޮންމެ ނަފްސަކަށްމެ، އެ ނަފްސެއް ހޯދިކަމެއްގެ ޖަޒާދެއްވުމަށެވެ. އަދި އެއުރެންނަކަށް ބޭއިންސާފެއް ނުކުރައްވާހުށްޓެވެ.","",""],["","","","أفرأيت من اتخذ إلهه هواه وأضله الله على علم وختم على سمعه وقلبه وجعل على بصره غشاوة فمن يهديه من بعد الله أفلا تذكرون","ފަހެ، އެމީހެއްގެ އެދުންތައް އެއީ، އެމީހަކު އަޅުކަންކުރާ އިލާހެއްކަމުގައި ހަދައި، އަދި އިލްމު ލިބިފައިވުމާއެކުވެސް، ﷲ އެމީހަކު މަގުފުރައްދަވައި، އަދި އޭނާގެ އިވުމާއި، ހިތުގައި ސިއްކަގައްސަވައި، އަދި އޭނާގެ ލޮލުގައި ފަރުދާއެއްލައްވައިފިމީހާ، ކަލޭގެފާނު ދެކެވަޑައިގަތީމުތޯއެވެ؟ ﷲ މެނުވީ އެމީހަކަށް ތެދުމަގު ދައްކާނީ ފަހެ، ކާކުހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުން ހަނދުމަ ނުކުރަނީހެއްޔެވެ؟","",""],["","","","وقالوا ما هي إلا حياتنا الدنيا نموت ونحيا وما يهلكنا إلا الدهر وما لهم بذلك من علم إن هم إلا يظنون","އެއުރެން ބުނޫއެވެ. ތިމަންމެންގެ ދުނިޔޭގެ ދިރިއުޅުންމެނުވީ، އެހެން ދިރިއުޅުމެއްނެތެވެ. ތިމަންމެން ދިރިތިބެމުއެވެ. އަދި މަރުވަމުއެވެ. އަދި ޒަމާން މެނުވީ ތިމަންމެން ހަލާކެއް ނުކުރެތެވެ. އެކަމާމެދު އެއުރެންނަކަށް އެއްވެސް އިލްމެއް ނުވެއެވެ. އެއުރެންނީ ހީކުރާބަޔަކު ކަމުގައިމެނުވީ ނުވެތެވެ.","",""],["","","","وإذا تتلى عليهم آياتنا بينات ما كان حجتهم إلا أن قالوا ائتوا بآبائنا إن كنتم صادقين","އަދި އެބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ އާޔަތްތައް ބަޔާން ވެގެންވާގޮތުގައި ކިޔައިދެއްވާހިނދު، ތިޔަބައިމީހުން ތެދުވެރިންކަމުގައިވަނީނަމަ، ތިމަންމެންގެ ކާބަފައިން ތިމަންމެންނަށް ގެނެސްދޭށޭ ބުނުންމެނުވީ އެއުރެން ދައްކާނޭ ހުއްޖަތެއް ނުވެތެވެ.","",""],["","","","قل الله يحييكم ثم يميتكم ثم يجمعكم إلى يوم القيامة لا ريب فيه ولكن أكثر الناس لا يعلمون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲ ތިޔަބައިމީހުން ދިރުއްވައެވެ. ދެން އެޔަށްފަހު ތިޔަބައިމީހުން މަރުގަންނަވަތެވެ. ދެން ގިޔާމަތް ދުވަހަށް ތިޔަބައިމީހުން (ދިރުއްވައި) އެއްކުރައްވާނެތެވެ. އެކަމާމެދަކު ޝައްކެއްނެތެވެ. އެހެނެއްކަމަކު، މީސްތަކުންކުރެ ގިނަމީހުންނަކަށް (އެކަމެއް) ނޭނގެތެވެ.","",""],["","","","ولله ملك السماوات والأرض ويوم تقوم الساعة يومئذ يخسر المبطلون","އުޑުތަކާއި، ބިމުގެވެރިކަންވަނީ ﷲއަށެވެ. އަދި ގިޔާމަތްގެ ވަގުތު އަންނަދުވަހު، އެދުވަހުން ބާތިލުގެ އަހުލުވެރިން ގެއްލި ހަލާކުވެދާހުށްޓެވެ.","",""],["","","","وترى كل أمة جاثية كل أمة تدعى إلى كتابها اليوم تجزون ما كنتم تعملون","އަދި ކޮންމެ އުއްމަތެއްމެ ކަކޫޖަހައިގެންތިބޭތީ ތިބާޔަށް ފެންނާނެތެވެ. ކޮންމެ އުއްމަތް އެންމެ އެ އުއްމަތެއްގެ (ޢަމަލުގެ) ފަތުގެ ކައިރިޔަށް ގޮވައި ގެންނަވާނެތެވެ. (އަދި އެއުރެންނަށް އަންގަވާނެއެވެ.) ތިޔަބައިމީހުން ކޮށްއުޅުނު ކަންތަކަށް ތިޔަބައިމީހުންނަށް މިއަދު ޖަޒާ ދެއްވާނެތެވެ.","",""],["","","","هذا كتابنا ينطق عليكم بالحق إنا كنا نستنسخ ما كنتم تعملون","މިއީ ތިމަންރަސްކަލާނގެ ފަތެވެ. އެ ފަތް ތިޔަބައިމީހުންގެ މައްޗަށް ހައްގު ގޮތުގައި ހެކިދެއެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން ކޮށްއުޅުނު ޢަމަލުތައް (މަލާއިކަތުން މެދުވެރިކުރައްވައި) ލިޔުއްވީމެވެ.","",""],["","","","فأما الذين آمنوا وعملوا الصالحات فيدخلهم ربهم في رحمته ذلك هو الفوز المبين","ފަހެ، އީމާންވެ އަދި ސާލިހު ޢަމަލުތައްކުޅަމީހުން ދަންނާށެވެ! ފަހެ، އެއުރެންގެ ވެރިރަސްކަލާނގެ އެކަލާނގެ ރަހުމަތްގެ ތެރެޔަށް އެއުރެން ވައްދަވާނެތެވެ. ބަޔާންވެގެންވާ ނަސީބު ލިބުމަކީ ހަމައެއީއެވެ.","",""],["","","","وأما الذين كفروا أفلم تكن آياتي تتلى عليكم فاستكبرتم وكنتم قوما مجرمين","އަދި ކާފިރުވި މީހުން ދަންނާށެވެ! (އެއުރެންނަށް އަންގަވާނެތެވެ.) ފަހެ، ތިމަންރަސްކަލާނގެ އާޔަތްތައް ތިޔަބައިމީހުންގެ މައްޗަށް ކިޔައިދެއްވާކަމުގައި ނުވޭހެއްޔެވެ؟ ދެން ތިޔަބައިމީހުން ކިބުރުވެރިވެގަތީމުއެވެ. އަދި ކުށްވެރިބަޔަކު ކަމުގައި ތިޔަބައިމީހުން ވީމުއެވެ.","",""],["","","","وإذا قيل إن وعد الله حق والساعة لا ريب فيها قلتم ما ندري ما الساعة إن نظن إلا ظنا وما نحن بمستيقنين","އަދި ހަމަކަށަވަރުން، ﷲގެ ވައުދު ފުޅަކީ ހައްގު ތެދޭ، އަދި ގިޔާމަތާ ދޭތެރޭގައި ޝައްކެއްނެތޭ ބުނާހިނދު، ތިޔަބައިމީހުން ބުނަމުއެވެ. ގިޔާމަތަކީ ކޮންއެއްޗެއްކަން ތިމަންމެން ނުދަންނަމުއެވެ. ތިމަންމެން (އެކަމާމެދު) ހީއެއްނޫނީ ނުކުރަމުއެވެ. އަދި ޔަގީންކުރާބަޔަކު ކަމުގައި ތިމަންމެން ނުވަމުއެވެ.","",""],["","","","وبدا لهم سيئات ما عملوا وحاق بهم ما كانوا به يستهزئون","އަދި އެއުރެންކުރި ޢަމަލުތަކުގެ ނުބައިކަން އެއުރެންނަށް ފާޅުވިއެވެ. އަދި އެއުރެން ފުރައްސާރަކޮށްއުޅުނު ކަންތައްތައް (އެބަހީ: އެކަމުގެ އަޒާބު) އައިސް، އެއުރެން ވަށައިލިއެވެ.","",""],["","","","وقيل اليوم ننساكم كما نسيتم لقاء يومكم هذا ومأواكم النار وما لكم من ناصرين","އަދި އަންގަވާނެތެވެ. ތިޔަބައިމީހުންގެ މިދުވަހާ ބައްދަލުވާނެކަން ތިޔަބައިމީހުން ހަނދާންނައްތައިލި ފަދައިން، މިއަދު ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންގެ މަތިން ހަނދުމަނައްތަވާހުށީމެވެ. އަދި ތިޔަބައިމީހުން ތިބެނިވި ތަނަކީ ނަރަކަޔެވެ. އަދި ތިޔަބައިމީހުންނަށް ނަސްރު ދޭނޭ އެއްވެސް ބަޔަކު ނުވެތެވެ.","",""],["","","","ذلكم بأنكم اتخذتم آيات الله هزوا وغرتكم الحياة الدنيا فاليوم لا يخرجون منها ولا هم يستعتبون","އެއީ ތިޔަބައިމީހުން ﷲގެ އާޔަތްތައް، ފުރައްސާރައެއް ކަމުގައި ހެދިކަމަށްޓަކައެވެ. އަދި ދުނިޔޭގެ ދިރިއުޅުން ތިޔަބައިމީހުން ހެއްލުންތެރިކުރި ކަމަށްޓަކައެވެ. ފަހެ، މިއަދު އެއުރެން އެ ނަރަކަޔަކުން ނުނެރުއްވާނެތެވެ. އަދި އެކަލާނގެ ރުއްސަވާ މަގަށް އެނބުރި ދިޔުމަކަށް، އެއުރެންނަކަށް ތަނެއް ނުމެދެއްވާނޭމެއެވެ.","",""],["","","","فلله الحمد رب السماوات ورب الأرض رب العالمين","ފަހެ، ހަމްދު ހުރީ ﷲއަށެވެ. (އެއީ) އުޑުތަކުގެވެރި، އަދި ބިމުގެވެރި، އާލަމްތަކުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["","","","وله الكبرياء في السماوات والأرض وهو العزيز الحكيم","އަދި އުޑުތަކާއި، ބިމުގައި ޢަޡަމަތް ތެރިކަމާއި، ބާރުވެރިކަންވަނީ އެކަލާނގެއަށެވެ. އަދި އެކަލާނގެއީ، ޢަޒީޒުވަންތަ ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم حم","ح م (މި އަކުރުތަކުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.)","",""],["","","","تنزيل الكتاب من الله العزيز الحكيم","މިއީ ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ﷲގެ ހަޒުރަތުން ބާވައިލެއްވި ފޮތެވެ.","",""],["","","","ما خلقنا السماوات والأرض وما بينهما إلا بالحق وأجل مسمى والذين كفروا عما أنذروا معرضون","ތިމަންރަސްކަލާނގެ އުޑުތަކާއި، ބިމާއި، އެދެމެދުގައި ވާހާތަކެތި ހައްގު ގޮތުގައި، އަދި ކަނޑައަޅުއްވާފައިވާ މުއްދަތަކަށްމެނުވީ ނަހައްދަވަމެވެ. އަދި ކާފިރު ވިމީހުންނީ، އެއުރެންނަށް އިންޒާރުކުރައްވާ ކަންތަކަށް ފުރަގަސްދޭ ބަޔެކެވެ.","",""],["","","","قل أرأيتم ما تدعون من دون الله أروني ماذا خلقوا من الأرض أم لهم شرك في السماوات ائتوني بكتاب من قبل هذا أو أثارة من علم إن كنتم صادقين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ﷲ ފިޔަވައި ތިޔަބައިމީހުން އަޅުކަންކޮށްއުޅޭ ތަކެއްޗާމެދު، ތިޔަބައިމީހުން ނިކަން ޚަބަރު ދީބަލާށެވެ! އެއުރެން ބިމުންހެދީ ކޮންތަނެއްކަން، ތިޔަބައިމީހުން ތިމަންކަލޭގެފާނަށް ދައްކައިބަލާށެވެ! ނުވަތަ އުޑުތައް ހެދުމުގައި ބައިވެރިވުމެއް، އެއުރެންނަށް ވަނީހެއްޔެވެ؟ މީގެކުރިން (ބާވައިލެއްވި) ފޮތެއް ނުވަތަ އިލްމުގެ ތެރެއިން މިންވަރެއް، ތިމަންކަލޭގެފާނަށް ތިޔަބައިމީހުން ގެނެސްދީބަލާށެވެ! ތިޔަބައިމީހުންނީ، ތެދުވެރިންކަމުގައި ވާނަމައެވެ.","",""],["","","","ومن أضل ممن يدعو من دون الله من لا يستجيب له إلى يوم القيامة وهم عن دعائهم غافلون","ގިޔާމަތް ދުވަހަށް ދާނދެން، އެމީހަކަށް އިޖާބަ ނުދޭފަރާތަކަށް ﷲ ފިޔަވައި އަޅުކަންކޮށް، ދުއާ ކޮށްއުޅޭ މީހަކަށްވުރެން މަގުފުރެދުންބޮޑީ ކާކުހެއްޔެވެ؟ އަދި އެތަކެތިވަނީ، އެއުރެންގެ ދުއާތަކަށް ޣާފިލު ވެގެންނެވެ.","",""],["","","","وإذا حشر الناس كانوا لهم أعداء وكانوا بعبادتهم كافرين","އަދި މީސްތަކުން (ގިޔާމަތް ދުވަހުން) އެއްކުރައްވާހިނދު އެއުރެންނަށް، އެ ބުދުތައް އަދާވަތް ތެރިންކަމުގައި ވާނެތެވެ. އަދި އެތަކެއްޗަށް އަޅުކަންކުރި ކަމާމެދު އިންކާރުކުރާ ތަކެތި ކަމުގައި އެތަކެތި ވާނެތެވެ.","",""],["","","","وإذا تتلى عليهم آياتنا بينات قال الذين كفروا للحق لما جاءهم هذا سحر مبين","އަދި ތިމަންރަސްކަލާނގެ އާޔަތްތައް އެއުރެންނަށް ބަޔާންވެގެންވާ ގޮތުގައި ކިޔައިދެވޭހިނދު (އަދި) އެއުރެންގެގާތަށް ހައްގު ބަސްފުޅު އައިހިނދު، ކާފިރު ވިމީހުން އެ ބަސްފުޅާމެދު ބުނޫއެވެ. މިއީ ފާޅުވެގެންވާ ޖާދޫއެކެވެ.","",""],["","","","أم يقولون افتراه قل إن افتريته فلا تملكون لي من الله شيئا هو أعلم بما تفيضون فيه كفى به شهيدا بيني وبينكم وهو الغفور الرحيم","ނުވަތަ އެކަލޭގެފާނު އަމިއްލަފުޅަށް އެ ގުރްއާން ހެއްދެވިކަމަށް އެއުރެން ބުނަނީހެއްޔެވެ؟ ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނު އަމިއްލަފުޅަށް އެ ގުރްއާން ހައްދަވާފައިވާނަމަ، ފަހެ، ތިމަންކަލޭގެފާނަށްޓަކައި ﷲގެ ހަޒުރަތުން އެއްވެސްކަމެއް ތިޔަބައިމީހުންނަކަށް މިލްކުވެގެންނެއް ނުވެތެވެ. (އެބަހީ: ﷲގެ އަޒާބުން ތިޔަބައިމީހުންނަކަށް، ތިމަންކަލޭގެފާނު ސަލާމަތެއް ނުކުރެވޭނެތެވެ.) ތިޔަބައިމީހުން އެ ގުރްއާނާމެދު، ދައްކައިއުޅޭ ވާހަކަތައް، އެކަލާނގެ ދެނެވޮޑިގަތުން ބޮޑެވެ. ތިމަންކަލޭގެފާނާ، ތިޔަބައިމީހުންނާ ދެމެދުގައިވާ ހެކިވެރިޔަކަށް އެކަލާނގެ ފުދެއެވެ. އަދި އެކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","قل ما كنت بدعا من الرسل وما أدري ما يفعل بي ولا بكم إن أتبع إلا ما يوحى إلي وما أنا إلا نذير مبين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ރަސޫލުންގެ ތެރެއިން ފުރަތަމަ (ފޮނުއްވި) ރަސޫލަކު ކަމުގައި، ތިމަންކަލޭގެފާނު ނުވަމެވެ. ތިމަންކަލޭގެފާނާމެދު އަދި ތިޔަބައިމީހުންނާމެދުވެސް، ކަންތައް ކުރައްވާނެގޮތެއް، ތިމަންކަލޭގެފާނަކަށް އެނގިވަޑައެއް ނުގަންނަވަތެވެ. ތިމަންކަލޭގެފާނަށް އިއްވަވާ ވަހީއަކަށްމެނުވީ، ތިމަންކަލޭގެފާނު ތަބައެއް ނުވަމެވެ. އަދި ބަޔާންވެގެންހުރި އިންޒާރުކުރައްވާ ބޭކަލަކު ކަމުގައިމެނުވީ، ތިމަންކަލޭގެފާނު ނުވަމެވެ.","",""],["","","","قل أرأيتم إن كان من عند الله وكفرتم به وشهد شاهد من بني إسرائيل على مثله فآمن واستكبرتم إن الله لا يهدي القوم الظالمين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ޚަބަރު ދީބަލާށެވެ! އެ ގުރްއާނަކީ، ﷲގެ ހަޒުރަތު ންއައި ފޮތެއް ކަމަށްވެފައި، އަދި ތިޔަބައިމީހުން އެޔަށް ކާފިރު ވެއްޖެނަމަ (ތިޔަބައިމީހުންނީ، އަމިއްލަ ނަފްސަށް އަނިޔާވެރި ބަޔަކުކަމުގައި ނުވޭހެއްޔެވެ؟ (އަދި އިސްރާއީލުގެދަރިންކުރެ ހެކިދޭމީހަކު އެފޮތުގެ މައްޗަށް (އެއީ ތެދުކަމަށް) ހެކިދީފައެވެ. ފަހެ، އޭނާ (އެޔަށް) އީމާން ވިއެވެ. އަދި ތިޔަބައިމީހުން (އެއަށް އީމާން ނުވެ) ބޮޑާވެގެންފީމުއެވެ. ހަމަކަށަވަރުން، އަނިޔާވެރިބަޔަކަށް ﷲ ތެދުމަގެއް ނުދައްކަވަތެވެ.","",""],["","","","وقال الذين كفروا للذين آمنوا لو كان خيرا ما سبقونا إليه وإذ لم يهتدوا به فسيقولون هذا إفك قديم","އަދި ކާފިރު ވިމީހުން އީމާންވި މީހުންނަށް ބުނޫއެވެ. (އެކަލޭގެފާނު ގެންނެވި ތަކެއްޗަށް އީމާން ވުމަކީ) އެއީ ހެޔޮކަމެއް ކަމުގައިވީނަމަ، ތިމަންމެންގެ މައްޗަކަށް އެއުރެން އެކަމަށް އިސްނަގައިގެން ނުދިޔައީހެވެ. އަދި އެއުރެންނަށް އެއިން ތެދުމަގު ނުލިބުނުހިނދު، ފަހެ، އެއުރެން ބުނާނެތެވެ. މިއީ އިހުގެ (ފުލޯކުގެ ތެރެއިންވާ) ދޮގެކެވެ.","",""],["","","","ومن قبله كتاب موسى إماما ورحمة وهذا كتاب مصدق لسانا عربيا لينذر الذين ظلموا وبشرى للمحسنين","އަދި އޭގެކުރިން މޫސާގެފާނަށް ބާވައިލެއްވި ފޮތަކީ، އެޔަށް ތަބާ ވެވޭ ފޮތެއްކަމުގައްޔާއި، ރަހުމަތެއްކަމުގައިވިއެވެ. އަދި މިއީ (އެބަހީ: މި ގުރްއާނަކީ) ކުރީގެ ފޮތްތައް ތެދުކުރަނިވިގޮތުގައި އަރަބި ބަހުންއޮތް ފޮތެކެވެ. އަނިޔާވެރިވި މީހުންނަށް އިންޒާރުކުރެއްވުމަށްޓަކައެވެ. އަދި އިހްސާން ތެރިންނަށް އުފާވެރި ޚަބަރެއް ކަމުގައެވެ.","",""],["","","","إن الذين قالوا ربنا الله ثم استقاموا فلا خوف عليهم ولا هم يحزنون","ހަމަކަށަވަރުން، ތިމަންމެންގެ ވެރިރަސްކަލާނގެއީ، ﷲ އޭ ބުނެ، ދެން ސީދާވެގަތްމީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެންގެ މައްޗަކަށް ބިރެއްނެތެވެ. އަދި އެއުރެންނީ ހިތާމަކުރާނޭ ބަޔަކުކަމުގައިވެސް ނުމެވޭމެއެވެ.","",""],["","","","أولئك أصحاب الجنة خالدين فيها جزاء بما كانوا يعملون","އެއުރެންނީ، ސުވަރުގޭގެ އަހުލުވެރިންނެވެ. އެތާނގައި، އެއުރެން ދެމިތިބެނިވިގޮތުގައެވެ. (އެއީ) އެއުރެން ކޮށްއުޅުނު ޢަމަލުތަކަށް ޖަޒާއެއްކަމުގައެވެ.","",""],["","","","ووصينا الإنسان بوالديه إحسانا حملته أمه كرها ووضعته كرها وحمله وفصاله ثلاثون شهرا حتى إذا بلغ أشده وبلغ أربعين سنة قال رب أوزعني أن أشكر نعمتك التي أنعمت علي وعلى والدي وأن أعمل صالحا ترضاه وأصلح لي في ذريتي إني تبت إليك وإني من المسلمين","އިންސާނާއަށް އޭނާގެ މައިންބަފައިންނަށް ހެޔޮކޮށް ހިތުމަށް ތިމަންރަސްކަލާނގެ ވަސިއްޔަތްކުރެއްވީމެވެ. އޭނާގެ މައިމީހާ އުނދަގުލާއި، ތުރާލާއެކު މާބަނޑުގައި އޭނާ އުފުލިއެވެ. އަދި އުނދަގުލާއި، ތުރާލާއެކު އޭނާ ވިހެއެވެ. އަދި އޭނާއާއިގެން މާބަނޑުވުމާއި، ކިރުތުނބުން ވީއްލުމުގެ މުއްދަތަކީ ތިރީސްމަސްދުވަހެވެ. އޭނާ ފުރާފުރިހަމަވެ، ސާޅީސްއަހަރު ފުރިއްޖެހިނދު، އޭނާ ބުނެތެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! އިބަރަސްކަލާނގެ މިއަޅާގެ މައްޗަށާއި، މިއަޅާގެ މައިންބަފައިންގެ މައްޗަށް ދެއްވި ނިއުމަތަށް ޝުކުރުކުރުމަށާއި، އިބަރަސްކަލާނގެ ރުހިވޮޑިގެންވާ ސާލިހު ޢަމަލުކުރުމަށް މިއަޅާއަށް އިލްހާމްކުރައްވާނދޭވެ! އަދި މިއަޅާގެ ދަރިފަސްކޮޅު، މިއަޅާއަށްޓަކައި އިސްލާހު ކޮށްދެއްވާނދޭވެ! ހަމަކަށަވަރުން، ތިމަންއަޅާ އިބަރަސްކަލާނގެޔަށް ތައުބާ ވެއްޖައީމެވެ. ހަމަކަށަވަރުން، ތިމަންއަޅާވަނީ މުސްލިމުންގެ ތެރެއިންނެވެ.","",""],["","","","أولئك الذين نتقبل عنهم أحسن ما عملوا ونتجاوز عن سيئاتهم في أصحاب الجنة وعد الصدق الذي كانوا يوعدون","އެއުރެންނީ، އެއުރެން ކުޅަ ހެޔޮކަންބޮޑު ޢަމަލުތައް އެއުރެންގެ ކިބައިން ތިމަންރަސްކަލާނގެ ގަބޫލުކުރައްވައި، އެއުރެންގެ ކުށްތައް ތިމަންރަސްކަލާނގެ ފުއްސަވައި، ސުވަރުގޭގެ އަހުލުވެރިންގެ ތެރޭގައި ލައްވާނެ މީހުންނެވެ. (އެއީ) އެއުރެންނަށް ވައުދުކުރައްވަމުން ގެންދެވި ތެދު ވައުދެވެ.","",""],["","","","والذي قال لوالديه أف لكما أتعدانني أن أخرج وقد خلت القرون من قبلي وهما يستغيثان الله ويلك آمن إن وعد الله حق فيقول ما هذا إلا أساطير الأولين","އެމީހެއްގެ މައިންބަފައިންނާ ދިމާޔަށް ތިޔަ ދެމީހުންނަށް ނުބައިކަންހުށްޓޭ ބުނިމީހާ (ދަންނާށެވެ!) ތިމަންގެކުރިން އެތައް ޖީލެއް ފާއިތުވެގޮސްފައިވާއިރު (ކަށްވަޅުން) ތިމަން ނެރުއްވާނެކަމަށް، ތިޔަ ދެމީހުން ތިމަންނައަށް ވައުދުކުރަނީ ހެއްޔެވެ؟ ﷲގެ ހަޒުރަތުން ސަލާމަތަށްއެދި، އެދެމީހުން ދުއާކުރަމުން (ބުނެތެވެ.) ކަލެޔަށް ހަލާކުހުށްޓެވެ! ކަލޭ ނިކަން އީމާން ވެބަލާށެވެ! ހަމަކަށަވަރުން، ﷲގެ ވައުދު ފުޅަކީ ހައްގު ތެދެވެ. ފަހެ، އޭނާ ބުނެތެވެ. ތިޔައީ އެވޭލާމީހުން ދައްކައިއުޅުނު ފުލޯކު ވާހަކަތައް ކަމުގައި މެނުވީ ނުވެތެވެ.","",""],["","","","أولئك الذين حق عليهم القول في أمم قد خلت من قبلهم من الجن والإنس إنهم كانوا خاسرين","ޖިންނީންނާއި، އިންސީންގެ ތެރެއިން، އެއުރެންގެކުރިން އިސްވެދިޔަ އުއްމަތްތަކުގެ ތެރޭގައި ކޯފާގެ ބަސްފުޅު ހައްގުވި މީހުންނީ، އެއުރެންނެވެ. ހަމަކަށަވަރުން، ގެއްލެނިވެގެންވާ ބަޔަކުކަމުގައި އެއުރެންވޫއެވެ.","",""],["","","","ولكل درجات مما عملوا وليوفيهم أعمالهم وهم لا يظلمون","އަދި ކޮންމެބަޔަކަށްމެ، އެބަޔަކު ކުޅަ ޢަމަލަކާ އެއްގޮތަށް ދަރަޖަތަކެއް ހުށްޓެވެ. (އެއީ) އެއުރެންނަށް، އެއުރެންގެ ޢަމަލުތަކުގެ ޖަޒާ ފުރިހަމަޔަށް ދެއްވުމަށްޓަކައެވެ. އަދި އެއުރެންނަކަށް ބޭއިންސާފެއް ނުކުރައްވާހުށްޓެވެ.","",""],["","","","ويوم يعرض الذين كفروا على النار أذهبتم طيباتكم في حياتكم الدنيا واستمتعتم بها فاليوم تجزون عذاب الهون بما كنتم تستكبرون في الأرض بغير الحق وبما كنتم تفسقون","ކާފިރު ވިމީހުން ނަރަކަޔަށް ހުށަހަޅުއްވާ ދުވަހު (އެއުރެންނަށް އަންގަވާނެތެވެ.) ތިޔަބައިމީހުންނަށްހުރި ރަނގަޅު ތަކެތި، ތިޔަބައިމީހުންގެ ދުނިޔޭގެ ހަޔާތުގައި ނަގާލައި އަދި ތިޔަބައިމީހުން އެއިން އަރާމުލިބިގެންފީމުއެވެ. ފަހެ، ހައްގަކާނުލައި ބިމުގައި ތިޔަބައިމީހުން ބޮޑާވެ އުޅުނުކަމަށްޓަކައި، އަދި ތިޔަބައިމީހުން ފާސިގު ވެގަތް ކަމަށްޓަކައި، މިއަދު އިހާނެތިކަމުގެ ޖަޒާ ތިޔަބައިމީހުންނަށް ލިބޭނެތެވެ.","",""],["","","","واذكر أخا عاد إذ أنذر قومه بالأحقاف وقد خلت النذر من بين يديه ومن خلفه ألا تعبدوا إلا الله إني أخاف عليكم عذاب يوم عظيم","ޢާދު ބާގައިމީހުންގެ އަޚު (ހޫދުގެފާނު) ގެ ވާހަކަ ކަލޭގެފާނު ކިޔައިދެއްވާށެވެ! (އެއީ) ވެލިފަރުބަދަތަކުގައިވާ، އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް އެކަލޭގެފާނު އިންޒާރުކުރެއްވި ހިނދެވެ. އެކަލޭގެފާނުގެ ކުރިންނާއި، އެކަލޭގެފާނުގެ ފަހުން އިންޒާރުކުރައްވާ ރަސޫލު ންވަނީ، އިސްވެގޮސްފައިކަން ކަށަވަރެވެ. ތިޔަބައިމީހުން ﷲއަށް މެނުވީ އަޅުކަން ނުކުރާހުށިކަމެވެ! ހަމަކަށަވަރުން، ބޮޑުވެގެންވާ ދުވަހެއްގެ އަޒާބާމެދު، ތިޔަބައިމީހުންގެ މައްޗަށް އަހުރެން ބިރުގަންނަމެވެ.","",""],["","","","قالوا أجئتنا لتأفكنا عن آلهتنا فأتنا بما تعدنا إن كنت من الصادقين","އެއުރެން ބުނޫއެވެ. ކަލޭގެފާނު ތިޔަވަޑައިގަތީ، ތިމަންމެންގެ އިލާހުންނަށް އަޅުކަން ކުރުމުން ތިމަންމެން ދުރުކުރެއްވުމަށްތޯއެވެ؟ ފަހެ، ކަލޭގެފާނު ތެދުވެރިންގެ ތެރެއިންވާނަމަ، ތިމަންމެންނަށް ތިޔަ ވައުދުކުރައްވާކަންތައް ތިމަންމެންގެގާތަށް ގެންނަވައިބައްލަވާށެވެ!","",""],["","","","قال إنما العلم عند الله وأبلغكم ما أرسلت به ولكني أراكم قوما تجهلون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ދެނެވޮޑިގަތުންވާ ކަންކަށަވަރީ ﷲގެ ހަޒުރަތު ގައެވެ. އަދި ތިމަންކަލޭގެފާނު އެކަމަކާއިގެން ފޮނުއްވެވި ކަންތައް، ތިޔަބައިމީހުންނަށް ތިމަންކަލޭގެފާނު އިއްވަނީއެވެ. އެހެނެއްކަމަކު ތިޔަބައިމީހުންނީ، ޖާހިލުބަޔަކު ކަމުގައި ތިމަންކަލޭގެފާނު ދެކެވަޑައިގަންނަވަމެވެ.","",""],["","","","فلما رأوه عارضا مستقبل أوديتهم قالوا هذا عارض ممطرنا بل هو ما استعجلتم به ريح فيها عذاب أليم","ފަހެ، އެއުރެންގެ ވާދީތަކާދިމާޔަށް ކުރިމަތިލައި، އުދަރެހަށް ހުރަސްވީ ވިލާގަނޑެއްގެ ސިފައިގައި އެއުރެންނަށް އެ (އަޒާބު) ފެނުނުހިނދު އެއުރެން ބުނޫއެވެ. މިއީ ތިމަންމެންނަށް ވާރޭވެއްސައިދޭނޭ ވިލާގަނޑެކެވެ. (އެންގެވިއެވެ.) އަދި ކިއެއްތަ! އެއީ އަވަސްވުމަށް ތިޔަބައިމީހުން އެދިގެންއުޅުނު ކަންތަކެވެ. ވޭންދެނިވި އަޒާބު އޭގައި ހިމެނިގެންވާ ގަދަވަޔެކެވެ.","",""],["","","","تدمر كل شيء بأمر ربها فأصبحوا لا يرى إلا مساكنهم كذلك نجزي القوم المجرمين","އެ ވައި، އޭގެ ވެރިރަސްކަލާނގެ އަމުރުފުޅަށް ކޮންމެއެއްޗެއް ހަލާކުކޮށް ނެތިކޮށްލަތެވެ. ފަހެ، އެއުރެން އުޅުނު ތަންތަންމެނުވީ، ފެންނާންނެތްބަޔަކު ކަމުގައި އެއުރެން ވެއްޖައޫއެވެ. ކުށްވެރިވިމީހުންނަށް ތިމަންރަސްކަލާނގެ ޖަޒާދެއްވަނީ އެފަދައިންނެވެ.","",""],["","","","ولقد مكناهم فيما إن مكناكم فيه وجعلنا لهم سمعا وأبصارا وأفئدة فما أغنى عنهم سمعهم ولا أبصارهم ولا أفئدتهم من شيء إذ كانوا يجحدون بآيات الله وحاق بهم ما كانوا به يستهزئون","އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެކަންކަމުގެ ބާރު ތިޔަބައިމީހުންނަށް ދެއްވާފައިނުވާ ކަންކަމުގައި، އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ބާރުދެއްވީމެވެ. އަދި އެއުރެންނަށް އިވުމާއި، ފެނުމާއި، ހިތްތައް، ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ. ފަހެ، އެއުރެން ﷲގެ އާޔަތްތަކަށް ދެކޮޅުހަދަމުން ދިއުމުގެ ސަބަބުން، އެއުރެންގެ އިވުމެއްވެސް، އަދި އެއުރެންގެ ފެނުމެއްވެސް، އަދި އެއުރެންގެ ހިތްތަކެއްވެސް އެއުރެންނަކަށް އެއްވެސްކަމެއް ފުއްދައެއް ނުދިނެވެ. އަދި އެއުރެން ފުރައްސާރަކޮށްއުޅުނު ކަންތައްއައިސް އެއުރެން ވަށައިލިއެވެ.","",""],["","","","ولقد أهلكنا ما حولكم من القرى وصرفنا الآيات لعلهم يرجعون","އަދި ހަމަކަށަވަރުން، ރަށްތަކުގެ ތެރެއިން ތިޔަބައިމީހުންގެ ވަށައިގެންވާ ތަންތަން ތިމަންރަސްކަލާނގެ ހަލާކުކުރެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ ހުއްޖަތްތައް ތަފާތުގޮތްގޮތަށް ބަޔާންކޮށްދެއްވީމެވެ. (އެއީ ތެދުމަގަށް) އެއުރެން އެނބުރި ރުޖޫއަ ވުމަށްޓަކައެވެ.","",""],["","","","فلولا نصرهم الذين اتخذوا من دون الله قربانا آلهة بل ضلوا عنهم وذلك إفكهم وما كانوا يفترون","ފަހެ، ﷲ ފިޔަވައި އެކަލާނގެ ހަޒުރަތަށް ކުއްތަންވެގަތުމުގެގޮތުން އެހެން އިލާހުންތަކެއް ހިފިމީހުންނަށް އެ އިލާހު ންތައް ނަސްރު ނުދިނީ ކީއްވެގެންހެއްޔެވެ؟ އަދި ކިއެއްތަ! އެއުރެންގެ ކިބައިން އެ އިލާހު ންތައް ގެއްލިހިނގައްޖެއެވެ. އަދި އެއީ އެއުރެންހެދި ދޮގެކެވެ. އަދި އެއުރެން ދޮގުން އުފައްދައިގެން ބުނެއުޅުނު ބުނުންތަކެކެވެ.","",""],["","","","وإذ صرفنا إليك نفرا من الجن يستمعون القرآن فلما حضروه قالوا أنصتوا فلما قضي ولوا إلى قومهم منذرين","ތިމަންރަސްކަލާނގެ ޖިންނީންގެ ތެރެއިންބަޔަކު، ގުރްއާންގެ އަޑުއެހުމަށް ކަލޭގެފާނުގެ އަރިހަށް ފޮނުއްވިހިނދު ހަނދުމަކުރައްވާށެވެ! ފަހެ، އެއުރެން، އެކަލޭގެފާނުގެ އަރިހަށް ޙާޒިރުު ވިހިނދު (އެކަކު އަނެކަކަށް) ބުނޫއެވެ. ތިޔަބައިމީހުން ކަނުލައި އަހައިބަލާށެވެ! ދެންފަހެ ކިޔަވައިވިދާޅުވެ ނިމުމުން އެއުރެން، އެއުރެންގެ ގައުމުގެމީހުންގެ ގާތަށް އިންޒާރުކުރާ ބަޔެއްގެގޮތުގައި އެނބުރި ހިނގައްޖައޫއެވެ.","",""],["","","","قالوا يا قومنا إنا سمعنا كتابا أنزل من بعد موسى مصدقا لما بين يديه يهدي إلى الحق وإلى طريق مستقيم","އެއުރެން ބުނޫއެވެ. އޭ އަހުރެމެންގެ ގައުމުގެމީހުންނޭވެ! ހަމަކަށަވަރުން، މޫސާގެފާނަށްފަހު، ބާވައިލެއްވެވި ފޮތެއް އަހުރެމެން އަހައިފީމުއެވެ. އޭގެކުރީގެ ފޮތްތައް ތެދުކުރަނިވި ގޮތުގައެވެ. ހައްގު ގޮތަށާއި، ސީދާވެގެންވާ ތެދުމަގަށް އެފޮތް މަގުދައްކަތެވެ.","",""],["","","","يا قومنا أجيبوا داعي الله وآمنوا به يغفر لكم من ذنوبكم ويجركم من عذاب أليم","އޭ އަހުރެމެންގެ ގައުމުގެމީހުންނޭވެ! ﷲގެ މަގަށް ގޮވައިލައްވާ ނަބިއްޔާއަށް (އެބަހީ: މުޙައްމަދުގެފާނަށް) ތިޔަބައިމީހުން އިޖާބަދޭށެވެ! އަދި ތިޔަބައިމީހުން އެކަލޭގެފާނަށް އީމާން ވާށެވެ! (އޭރުން) އެކަލާނގެ ތިޔަބައިމީހުންގެ ފާފަތައްފުއްސަވައި، ވޭންދެވިނި އަޒާބުން އެކަލާނގެ ތިޔަބައިމީހުން ދިންނަވާނެތެވެ.","",""],["","","","ومن لا يجب داعي الله فليس بمعجز في الأرض وليس له من دونه أولياء أولئك في ضلال مبين","އަދި ﷲގެ މަގަށް ގޮވައިލައްވާ ނަބިއްޔާއަށް އިޖާބަ ނުދޭމީހާ (ދަންނާށެވެ!) ފަހެ، އޭނާއީ ބިމުގައި (ﷲ) ނުކުޅައްދާ މީހަކު ކަމުގައި ނުވެތެވެ. އަދި އެކަލާނގެ ފިޔަވައި އޭނާޔަށް އެހީތެރި ފަރާތްތަކެއްވެސް ނުވެތެވެ. އެއުރެންވަނީ ފާޅުވެގެންވާ ފުރެދުމެއްގައެވެ.","",""],["","","","أولم يروا أن الله الذي خلق السماوات والأرض ولم يعي بخلقهن بقادر على أن يحيي الموتى بلى إنه على كل شيء قدير","އުޑުތަކާއި، ބިންހެއްދެވި އަދި އެތަންތަން ހެއްދެވުމުގައި އެއްވެސްކަހަލަ ނުކުޅެދުމެއް ލިބިވޮޑިގެންނުވާ ﷲއީ، މަރުވެފައިވާ ތަކެތި ދިރުއްވެވުމަށް ކުޅަދުންވަންތަ ކަލާނގެކަން އެއުރެންނަށް ނޭނގެނީހެއްޔެވެ؟ އެހެންނަކުންނޫނެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ويوم يعرض الذين كفروا على النار أليس هذا بالحق قالوا بلى وربنا قال فذوقوا العذاب بما كنتم تكفرون","ކާފިރު ވިމީހުން ނަރަކަޔަށް ހުށަހަޅުއްވާދުވަހު (އެއުރެންނަށް އަންގަވާނެތެވެ.) މިއީ ހައްގު ތެދުކަމުގައި ނުވޭހެއްޔެވެ؟ އެއުރެން ބުނާނެތެވެ. އެހެންނަކުންނޫނެވެ! އަހަރެމެންގެ ވެރިރަސްކަލާނގެ ގަންދީބުނަމެވެ. (މިއީ ހައްގު ތެދެވެ.) އެކަލާނގެ ވަހީކުރައްވާނެތެވެ. ފަހެ، ތިޔަބައިމީހުން ކާފިރުވެ އުޅުނުކަމަށްޓަކައި ވޭންދެނިވި އަޒާބުގެރަހަ ތިޔަބައިމީހުން ލިބިގަންނާށެވެ!","",""],["","","","فاصبر كما صبر أولو العزم من الرسل ولا تستعجل لهم كأنهم يوم يرون ما يوعدون لم يلبثوا إلا ساعة من نهار بلاغ فهل يهلك إلا القوم الفاسقون","ފަހެ، ރަސޫލުންގެ ތެރެއިން ގަދަހިތްވަރުފުޅުގެވެރި ރަސޫލުން (އެބަހީ: އުލުލްޢަޒްމުގެ ބޭކަލުން) ކެތްކުރެއްވި ފަދައިން ކަލޭގެފާނުވެސް ކެތްތެރިވެ ވަޑައިގަންނަވާށެވެ! އަދި އެއުރެންނަށް (އަޒާބު) އަވަސްވުމަށް ކަލޭގެފާނު އެދިވަޑައިނުގަންނަވާށެވެ! އެއުރެންނަށް ވައުދުކުރައްވާ ކަންތައް (އެބަހީ: އަޒާބު) އެއުރެން ދެކޭދުވަހު، ދުވާލަކުން އެންމެގަޑިޔެއްގެ އިރުވެސް، ދުނިޔޭގައި ލަސްވެ ތިބިބަޔަކު ކަމުގައި އެއުރެން ނުވާފަދައެވެ. (މިއީ) ސާފުގޮތުގައި އިއްވަވާ އިއްވެވުމެކެވެ. ފަހެ، ފާސިގު ވިމީހުން މެނުވީ ހަލާކުވެގެން ނުދާނެތެވެ.","",""],["","","","بسم الله الرحمن الرحيم الذين كفروا وصدوا عن سبيل الله أضل أعمالهم","(ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް) ކާފިރުވެ، އަދި ﷲގެމަގުން (އެހެންމީހުން) އެއްކިބާކުރި މީހުންގެ ޢަމަލުތައް އެކަލާނގެ ބާތިލުކުރެއްވިއެވެ.","",""],["","","","والذين آمنوا وعملوا الصالحات وآمنوا بما نزل على محمد وهو الحق من ربهم كفر عنهم سيئاتهم وأصلح بالهم","އަދި އީމާންވެ، ސާލިހު ޢަމަލުތައްކޮށް، އަދި މުޙައްމަދުގެފާނުގެ މައްޗަށް ބާވައިލެއްވި ފޮތް އެއީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައި ހައްގު ބަސްފުޅުކަމަށް އީމާންވި މީހުން (ދަންނާށެވެ!) އެކަލާނގެ އެއުރެންގެ ކުށްފާފަތައް އެއުރެންގެ ކިބައިން ފުއްސަވައި، އަދި އެކަލާނގެ، އެއުރެންގެ ޙާލުތައް އިސްލާހުކުރެއްވިއެވެ.","",""],["","","","ذلك بأن الذين كفروا اتبعوا الباطل وأن الذين آمنوا اتبعوا الحق من ربهم كذلك يضرب الله للناس أمثالهم","އެއީ ކާފިރު ވިމީހުން، ބާތިލަށް ތަބާ ވީކަމުގެ ސަބަބުންނެވެ. އަދި އީމާން ވިމީހުން، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތު ންއައި ހައްގު ބަސްފުޅަށް ތަބާ ވުމުގެ ސަބަބުންނެވެ. މީސްތަކުންނަށް އެއުރެންގެ މިސާލުތައް ﷲ ޖައްސަވަނީ އެފަދައިންނެވެ.","",""],["","","","فإذا لقيتم الذين كفروا فضرب الرقاب حتى إذا أثخنتموهم فشدوا الوثاق فإما منا بعد وإما فداء حتى تضع الحرب أوزارها ذلك ولو يشاء الله لانتصر منهم ولكن ليبلو بعضكم ببعض والذين قتلوا في سبيل الله فلن يضل أعمالهم","ފަހެ، (ހަނގުރާމައިގެ މައިދާނުގައި) ތިޔަބައިމީހުން ކާފިރުންނާ ބައްދަލުވާހިނދު، އެއުރެންގެ ކަނދުރާތަކުގައި ޖަހައި ގަތުލުކުރާށެވެ! (ތިޔަބައިމީހުންގެ ބާރު ގަދަކޮށް) އެއުރެން ގަތުލުކުރުން ގިނަކޮށްފުމަށްދާނދެނެވެ. ފަހެ، (އެހިނދު އެއުރެން) ވަރުގަދަޔަށް ބަނދެ ހައްޔަރުކުރާށެވެ! ދެން އެޔަށްފަހު (އެބަހީ: ހަނގުރާމަ ނިމުމަށްފަހު) އޮތީ ތިޔަބައިމީހުން އެއުރެން ދޫކޮށްލުމެވެ. ނުވަތަ އެއުރެންގެ އަތުން ފިދުޔަ ނެގުމެވެ. (ތިޔަބައިމީހުން މިގޮތުގައި ދެމިތިބޭހުށީ) ހަނގުރާމައިގެ ހަތިޔާރުތައް ބަހައްޓައިފުމަށްދާނދެނެވެ. އެއުރެންނާމެދު ކަންތައް އޮތްގޮތީ އެއީއެވެ. އަދި، ﷲ އިރާދަކުރައްވާނަމަ (ހަނގުރާމަކުރުމަކާ ނުލައި) އެއުރެންގެ މައްޗަށް ތިޔަބައިމީހުންނަށް ނަސްރު ލިބުނީސްކަން ކަށަވަރެވެ. އެހެނެއްކަމަކު (ޖިހާދު ޝަރުއުކުރެއްވީ) ތިޔަބައިމީހުން އެއްބަޔަކު އަނެއްބަޔަކު އިމްތިހާނުކުރެއްވުމަށްޓަކައެވެ. އަދި، ﷲގެ މަގުގައި ގަތުލު ވީ މީހުން ފަހެ، އެއުރެންގެ ޢަމަލުތައް އެކަލާނގެ ގެއްލެނި ނުކުރައްވާނެތެވެ.","",""],["","","","سيهديهم ويصلح بالهم","އެކަލާނގެ އެއުރެންނަށް (ރަނގަޅު ކަންތަކަށް) މަގުދައްކަވާނެތެވެ. އަދި އެކަލާނގެ އެއުރެންގެ އެންމެހާ ޙާލުތައް، އިސްލާހުކުރައްވާނެތެވެ.","",""],["","","","ويدخلهم الجنة عرفها لهم","އަދި ސުވަރުގެޔަށް އެކަލާނގެ އެއުރެން ވައްދަވާނެތެވެ. އެ ސުވަރުގެ ވަނީ، އެއުރެންނަށް އަންގަވައި ބަޔާންކޮށްދެއްވާފައެވެ.","",""],["","","","يا أيها الذين آمنوا إن تنصروا الله ينصركم ويثبت أقدامكم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ﷲއަށް (އެބަހީ: ﷲގެ ދީނަށް) ނަސްރު ދޭނަމަ، އެކަލާނގެ ތިޔަބައިމީހުންނަށް ނަސްރު ދެއްވާނެތެވެ. އަދި އެކަލާނގެ ތިޔަބައިމީހުންގެ ފައިތިލަތައް ޘާބިތުކުރައްވާނެތެވެ.","",""],["","","","والذين كفروا فتعسا لهم وأضل أعمالهم","ކާފިރު ވިމީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެންނަށް ހަލާކާއި، އަބާއްޖަވެރިކަންހުށްޓެވެ. އަދި، އެކަލާނގެ އެއުރެންގެ ޢަމަލުތައް ގެއްލެނިކުރެއްވިއެވެ.","",""],["","","","ذلك بأنهم كرهوا ما أنزل الله فأحبط أعمالهم","އެއީ އެއުރެން، ﷲ ބާވައިލެއްވި ފޮތަށް ނުރުހުމުގެ ސަބަބުންނެވެ. ދެން އެކަލާނގެ އެއުރެންގެ ޢަމަލުތައް ބާތިލުކުރެއްވިއެވެ.","",""],["","","","أفلم يسيروا في الأرض فينظروا كيف كان عاقبة الذين من قبلهم دمر الله عليهم وللكافرين أمثالها","ފަހެ، އެއުރެން ބިމުގައި ދަތުރުފަތުރުކޮށް އެއުރެންގެ ކުރިން އުޅުނުމީހުންގެ ނިމުންވީ ކޮންފަދައަކުންކަން، ފަހެ، އެއުރެން ނުބަލަނީހެއްޔެވެ؟ އެއުރެންގެ މައްޗަށް ﷲ ހަލާކުފޮނުއްވައި ނެތިކުރެއްވިއެވެ. އަދި، ކާފިރުވި މީހުންނަށްހުރީ އެފަދަ އުގޫބާތް ތަކެވެ.","",""],["","","","ذلك بأن الله مولى الذين آمنوا وأن الكافرين لا مولى لهم","އެއީ އީމާންވި މީހުންނަށް އެހީތެރިވެ، ނަސްރު ދެއްވާ ފަރާތެއްކަމުގައި ﷲ ވޮޑިގެންވާކަމުންނެވެ. އަދި، ކާފިރުވި މީހުންނަށް އެހީތެރިވާނޭ އެއްވެސް ފަރާތެއް ނުވެއެވެ.","",""],["","","","إن الله يدخل الذين آمنوا وعملوا الصالحات جنات تجري من تحتها الأنهار والذين كفروا يتمتعون ويأكلون كما تأكل الأنعام والنار مثوى لهم","ހަމަކަށަވަރުން، އީމާންވެ ސާލިހު ޢަމަލުތައްކުޅަ މީހުން، އެތަންތާނގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކަށް ﷲ (އެއުރެން) ވައްދަވާނެތެވެ. އަދި ކާފިރު ވިމީހުން (ދުނިޔޭގެ ދިރުއުޅުމުގައި) އެއުރެން ފަސޭހަކަމާއި އަރާމު ލިބިގަނެ، ނަޢަމް ސޫފި ކައިއުޅޭފަދައިން އެއުރެން ކައިއުޅެތެވެ. އަދި އެއުރެން ތިބެނިވި ތަނަކީ ނަރަކަޔެވެ.","",""],["","","","وكأين من قرية هي أشد قوة من قريتك التي أخرجتك أهلكناهم فلا ناصر لهم","ކަލޭގެފާނު އެ ރަށަކުން ބޭރުކޮށް ނެރެލި، ކަލޭގެފާނުގެ ރަށަށްވުރެ ބާރުގަދަ ކިތައްކިތައް ރަށުގެ އަހުލުވެރިން، ތިމަންރަސްކަލާނގެ އެއުރެން ހަލާކުކުރައްވައި ނެތިކުރެއްވިންހެއްޔެވެ! ފަހެ، އެއުރެންނަށް ނަސްރު ދޭނޭ އެއްވެސް މީހަކު ނުވެއެވެ.","",""],["","","","أفمن كان على بينة من ربه كمن زين له سوء عمله واتبعوا أهواءهم","ފަހެ، އެމީހެއްގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އައި ސާފު ހެތްކެއްގެ މަތީގައިވާ މީހަކު، އެމީހެއްގެ ނުބައި ޢަމަލު އެމީހަކަށް ޒީނަތް ތެރިކުރައްވާފައިވާ މީހަކާއި، އެއުރެންގެ ހަވާނަފްސުގެ އެދުންތަކަށް ތަބާ ވެގެންވާ މީހުންނާ އެއްފަދަވެގެން ވޭހެއްޔެވެ؟","",""],["","","","مثل الجنة التي وعد المتقون فيها أنهار من ماء غير آسن وأنهار من لبن لم يتغير طعمه وأنهار من خمر لذة للشاربين وأنهار من عسل مصفى ولهم فيها من كل الثمرات ومغفرة من ربهم كمن هو خالد في النار وسقوا ماء حميما فقطع أمعاءهم","ތަގުވާވެރިންނަށް ވައުދުކުރައްވާފައިވާ ސުވަރުގޭގެ މިސާލަކީ އެތާނގައި ތަޣައްޔަރުކަމެއްނުވާ، ސާފު ފެނުގެ ކޯރުތަކާއި، އޭގެ ރަހަ ތަފާތުނުވާ ކިރުގެ ކޯރުތަކާއި، ބޯމީހުންނަށް މީރުރަހަ ލިބެނިވި، ރާގެ ކޯރުތަކާއި، ސާފު މާމުއިގެ ކޯރުތައްވާ ސުވަރުގެއެވެ. އަދި އެތާނގައި އެއުރެންނަށްޓަކައި ހުރިހާ ބާވަތެއްގެ މޭވާތަކާއި، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ފާފަފުއްސެވުންހުށްޓެވެ. (މި ހުރިހާ ނިއުމަތްތައް ލިބިގެންވާ މީހުންނާއި) އެމީހަކު ނަރަކައިގައި ދެމިހުރެ، އަދި ކެކިކެކިހުރި ހޫނުފެނުގެ ބުއިން އެއުރެންނަށް ބޯންދެއްވުމުން، އެއުރެންގެ ގޮހޮރުތައް ބުރިބުރިވެގެންދާ މީހުންނާ އެއްފަދަވެގެން ވޭހެއްޔެވެ؟","",""],["","","","ومنهم من يستمع إليك حتى إذا خرجوا من عندك قالوا للذين أوتوا العلم ماذا قال آنفا أولئك الذين طبع الله على قلوبهم واتبعوا أهواءهم","އެއުރެންގެ ތެރެއިން (އެބަހީ: ކާފިރުންގެ ތެރެއިން) ބަޔަކު، ކަލޭގެފާނު ވިދާޅުވާ ވިދާޅުވުމަށް އަހައިއުޅެތެވެ. ކަލޭގެފާނުގެ އަރިހުން އެއުރެން ނުކުންނަހިނދު، އިލްމު ލިބިގެންވާ މީހުންނަށް އެއުރެން ބުނެތެވެ. އެކަލޭގެފާނު ދެންމެއަކު ވިދާޅުވީ ކީކޭހެއްޔެވެ؟ އެއުރެންނީ، ﷲއެއުރެންގެ ހިތްތަކުގައި ސިއްކަގައްސަވައި، ބަންދުކުރައްވާފައިވާ މީހުންނެވެ. އަދި އެއުރެންނީ އެއުރެންގެ ހަވާނަފްސުގެ އެދުންތަކަށް ތަބާ ވެގެންވާ މީހުންނެވެ.","",""],["","","","والذين اهتدوا زادهم هدى وآتاهم تقواهم","ތެދުމަގު ލިބިގެންވާ މީހުންނަށް، އެކަލާނގެ ތެދުމަގު އިތުރުކުރެއްވިއެވެ. އަދި އެއުރެން ތަގުވާވެރިވެ، ރައްކާތެރިވުމުގެ މަގު އެކަލާނގެ އެއުރެންނަށް ފަހިކޮށްދެއްވިއެވެ.","",""],["","","","فهل ينظرون إلا الساعة أن تأتيهم بغتة فقد جاء أشراطها فأنى لهم إذا جاءتهم ذكراهم","ފަހެ، އެއުރެންނަށް ނޭނގިތިއްބައި، ކުއްލިޔަކަށް ގިޔާމަތް ވުމުގެ ވަގުތު އަތުވެދާނެކަމަށް މެނުވީ، އެއުރެން އިންތިޒާރުކުރޭހެއްޔެވެ؟ ފަހެ، ހަމަކަށަވަރުން، އެކަމުގެ ޢަލާމާތްތައް އަތުވެއްޖެއެވެ. ފަހެ، އެކަން އެއުރެންނާ ހަމަޔަށް އަތުވެއްޖެހިނދު، އެއުރެންގެ ހަނދުމަކުޅައުންވަނީ ކިހިނަކުންހެއްޔެވެ؟","",""],["","","","فاعلم أنه لا إله إلا الله واستغفر لذنبك وللمؤمنين والمؤمنات والله يعلم متقلبكم ومثواكم","ފަހެ، ﷲ މެނުވީ އިލާހަކު ނުވާކަން ކަލޭގެފާނު ދެނެވަޑައިގަންނަވާށެވެ! އަދި ކަލޭގެފާނުގެ ކުށަށާއި، މުއުމިނު ފިރިހެނުންނަށާއި، މުއުމިނު އަންހެނުންނަށް ކަލޭގެފާނު ފާފަފުއްސެވުމަށް އެދިވަޑައިގަންނަވާށެވެ! ތިޔަބައިމީހުން ހިނގާބިނގާއުޅޭ ތަނާއި، އަރާމުކުރަންތިބޭ ތަން ﷲ ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","ويقول الذين آمنوا لولا نزلت سورة فإذا أنزلت سورة محكمة وذكر فيها القتال رأيت الذين في قلوبهم مرض ينظرون إليك نظر المغشي عليه من الموت فأولى لهم","އީމާންވި މީހުން ބުނެތެވެ. ސޫރަތެއް ބާވައިނުލެއްވީ ކީއްވެބާވައެވެ؟ އަދި ސަރީހަ ކަނޑައަޅުއްވާފައިވާ ސޫރަތެއް ބާވައިލައްވާފައި އަދި ހަނގުރާމައިގެ ވާހަކަ އެ ސޫރަތުގައި ބަޔާންކުރައްވައިފިހިނދު، މަރަށް ހޭނެތިފައިވާ މީހަކު ބަލާފަދައިން އެއުރެންގެ ހިތްތަކުގައި (ނިފާގުގެ) ބަލިމަޑުކަމެއްވާ މީހުން ކަލޭގެފާނަށް ބަލާތީ ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނޫއެވެ. ފަހެ، އެއުރެންނަށް ހަލާކުހުށްޓެވެ.","",""],["","","","طاعة وقول معروف فإذا عزم الأمر فلو صدقوا الله لكان خيرا لهم","ކިޔަމަންވުމަކާއި، ރީތި ބަހެއް ބުނުން (ހެޔޮކަން ބޮޑުވެގެން) ވެއެވެ. ފަހެ، ހަނގުރާމަކުރުމުގެ އަމުރުފުޅު ކަނޑައެޅިއްޖެހިނދު، ﷲއަށް އެއުރެން ތެދުވެރިވީނަމަ، އެކަން އެއުރެންނަށް ހެޔޮކަންބޮޑުވީސްކަން ކަށަވަރެވެ.","",""],["","","","فهل عسيتم إن توليتم أن تفسدوا في الأرض وتقطعوا أرحامكم","ފަހެ، ތިޔަބައިމީހުން ފުރަގަސްދީ، އެނބުރި ހިނގައްޖެނަމަ (ކުރިޔެކޭ އެއްފަދައިން) ތިޔަބައިމީހުން ބިމުގައި ފަސާދަ ކޮށް، އަދި ތިޔަބައިމީހުންގެ ގާތްތިމާގެކަމުގެ ގުޅުންތައް ކަނޑައިފުމަށް ތިޔަބައިމީހުން ގާތްވެގެންވޭ ނޫންހެއްޔެވެ؟","",""],["","","","أولئك الذين لعنهم الله فأصمهم وأعمى أبصارهم","އެއުރެންނީ، އެއުރެންނަށް ﷲ ލައުނަތް ލެއްވި މީހުންނެވެ. ފަހެ، އެކަލާނގެ އެއުރެން ބީރުކުރައްވައި، އަދި އެއުރެންގެ ލޯތައް ކަނުކުރެއްވިއެވެ.","",""],["","","","أفلا يتدبرون القرآن أم على قلوب أقفالها","ފަހެ، ގުރްއާނާމެދު އެއުރެން ވިސްނައި ފިކުރު ނުކުރަނީހެއްޔެވެ؟ ނުވަތަ (އެއުރެންގެ) ހިތްތަކުގައި ތަޅުތަކެއް ލެވިފައިވަނީ ހެއްޔެވެ؟","",""],["","","","إن الذين ارتدوا على أدبارهم من بعد ما تبين لهم الهدى الشيطان سول لهم وأملى لهم","ހަމަކަށަވަރުން، އެއުރެންނަށް ތެދުމަގު އެނގި ބަޔާންވުމަށްފަހު، އެއުރެންގެ ފުރަގަހަށް އެނބުރިދިޔަ މީހުންނަށް ޝައިތާނާ އެކަން ޒީނަތް ތެރިކޮށްދެއްކިއެވެ. އަދި އަޖަލުތައް ދިގުވާނެކަމުގެ އެދުން އެއުރެންނަށް ލައިދިނެވެ.","",""],["","","","ذلك بأنهم قالوا للذين كرهوا ما نزل الله سنطيعكم في بعض الأمر والله يعلم إسرارهم","އެއީ، ﷲ ބާވައިލެއްވި ފޮތަށް ނުރުހުންވި މީހުންނަށް، އެއުރެން ބުނިކަމަށްޓަކައެވެ. ބައެއްކަންތަކުގައި ތިމަންމެން ތިޔަބައިމީހުންނަށް ކިޔަމަންވާނޫއެވެ. އަދި އެއުރެން ސިއްރުކޮށްފައިވާ ގޮތް ﷲ ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","فكيف إذا توفتهم الملائكة يضربون وجوههم وأدبارهم","އެއުރެންގެ މޫނުތަކާއި، ބުރިކަށިތަކުގައި ތަޅުއްވަމުން މަލާއިކަތުން އެއުރެންގެ މަރުހިއްޕަވާހިނދު، އެއުރެންގެ ޙާލު ވާނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","ذلك بأنهم اتبعوا ما أسخط الله وكرهوا رضوانه فأحبط أعمالهم","އެއީ، ﷲ ކޯފާވެވޮޑިގެންވާމަގަށް އެއުރެން ތަބާ ވީކަމަށްޓަކައެވެ. އަދި އެކަލާނގެ ރުއްސެވުމަށް އެއުރެން ނުރުހުންވީކަމަށްޓަކައެވެ. ފަހެ، އެކަލާނގެ އެއުރެންގެ ޢަމަލުތައް ބާތިލުކުރެއްވިއެވެ.","",""],["","","","أم حسب الذين في قلوبهم مرض أن لن يخرج الله أضغانهم","ނުވަތަ އެއުރެންގެ ހިތްތަކުގައި (ނިފާގުގެ) ބަލިމަޑުކަމެއްވާ މީހުން، އެއުރެންގެ ރުޅިވެރިކަމާއި، ހަސަދަވެރިކަން ﷲ ފާޅުނުކުރައްވާނެކަމަށް އެއުރެން ހީކުރީހެއްޔެވެ؟","",""],["","","","ولو نشاء لأريناكهم فلعرفتهم بسيماهم ولتعرفنهم في لحن القول والله يعلم أعمالكم","އަދި، ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާނަމަ، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް އެއުރެން ދައްކަވައިފީމުސްކަން ކަށަވަރެވެ. ފަހެ، އެއުރެންގެ ނިޝާން ތަކުން ކަލޭގެފާނަށް އެއުރެން އެނގިވަޑައިގަތީސްކަން ކަށަވަރެވެ. އަދި ބަސްބުނުމުގެ ރާގުން ކަލޭގެފާނަށް އެއުރެން އެނގިވަޑައިގަންނަވާނެކަން ކަށަވަރެވެ. އަދި ﷲ ތިޔަބައިމީހުންގެ ޢަމަލުތައް ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","ولنبلونكم حتى نعلم المجاهدين منكم والصابرين ونبلو أخباركم","އަދި ތިޔަބައިމީހުންގެ ތެރެއިން ޖިހާދުކުރާ މީހުންނާއި، ކެތްތެރިވާ މީހުން، ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގެންވެ، އެކަން ހާމަވެއްޖައުމަށްދާނދެން އަދި ތިޔަބައިމީހުންގެ ޚަބަރުތައް އަންގަވައި ފާޅުކުރައްވައިފުމަށްދާނދެން ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން އިމްތިހާނުކުރައްވާހުށީމެވެ.","",""],["","","","إن الذين كفروا وصدوا عن سبيل الله وشاقوا الرسول من بعد ما تبين لهم الهدى لن يضروا الله شيئا وسيحبط أعمالهم","ހަމަކަށަވަރުން، ކާފިރުވެ، އަދި ﷲގެ މަގުން (އެހެންމީހުން) އެއްކިބާކޮށް، އަދި އެއުރެންނަށް ތެދުމަގު އެނގި ބަޔާންވުމަށްފަހު، ރަސޫލާއާ ދެކޮޅުވެރިވާ މީހުންނަކަށް، އެއްވެސް ކަމަކުން ﷲއަށް ގެއްލުމެއް ނުދެވޭނެތެވެ. އަދި އެކަލާނގެ އެއުރެންގެ ޢަމަލުތައް ބާތިލުކުރައްވާނެތެވެ.","",""],["","","","يا أيها الذين آمنوا أطيعوا الله وأطيعوا الرسول ولا تبطلوا أعمالكم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ﷲއަށް ކިޔަމަންވާށެވެ! އަދި ރަސޫލާއަށް ކިޔަމަންވާށެވެ! އަދި ތިޔަބައިމީހުންގެ ޢަމަލުތައް ތިޔަބައިމީހުން ބާތިލު ނުކުރާހުށިކަމެވެ!","",""],["","","","إن الذين كفروا وصدوا عن سبيل الله ثم ماتوا وهم كفار فلن يغفر الله لهم","ހަމަކަށަވަރުން، ކާފިރުވެ ﷲގެމަގުން (އެހެންމީހުން) އެއްކިބާކޮށް، ދެން ކާފިރު ންކަމުގައި ވެގެންތިބެ މަރުވި މީހުން (ދަންނާށެވެ!) ފަހެ، ﷲ، އެއުރެންނަކަށް ފާފައެއް ނުފުއްސަވާނެތެވެ.","",""],["","","","فلا تهنوا وتدعوا إلى السلم وأنتم الأعلون والله معكم ولن يتركم أعمالكم","ފަހެ، ތިޔަބައިމީހުން ނިކަމެތިވެގަނެ، ކާފިރުންނާ ސުލްހަ ވުމަށް ގޮވައިނޫޅޭށެވެ! ގަދަވެ، މަތިވެރިވާނޭ ބަޔަކީ ތިޔަބައިމީހުންނެވެ. އަދި، ﷲ ވޮޑިގެންވަނީ ތިޔަބައިމީހުންނާ އެކުގައެވެ. އަދި ތިޔަބައިމީހުންގެ ޢަމަލުތައް އެކަލާނގެ އުނިނުކުރައްވާހުށްޓެވެ.","",""],["","","","إنما الحياة الدنيا لعب ولهو وإن تؤمنوا وتتقوا يؤتكم أجوركم ولا يسألكم أموالكم","ދުނިޔޭގެ ދިރިއުޅުން ވާކަން ކަށަވަރީ، ކުޅިވަރެއްކަމުގައްޔާއި، މަޖަލެއްކަމުގައެވެ. އަދި ތިޔަބައިމީހުން އީމާންވެ، ތަގުވާވެރިވާނަމަ، އެކަލާނގެ ތިޔަބައިމީހުންގެ ދަރުމަ، ތިޔަބައިމީހުންނަށް ދެއްވާނެތެވެ. އަދި އެކަލާނގެ ތިޔަބައިމީހުންގެ މުދާތަކަކަށް އެދިވޮޑިއެއް ނުގަންނަވަތެވެ.","",""],["","","","إن يسألكموها فيحفكم تبخلوا ويخرج أضغانكم","ތިޔަބައިމީހުންގެ ކިބައިން އެކަލާނގެ އެތަކެއްޗަށް އެދިވޮޑިގަންނަވައި، އެކަމަށް ބާރުއަޅުއްވާނަމަ، ތިޔަބައިމީހުން ދަހިވެތިވާނޫއެވެ. އަދި އެކަލާނގެ ތިޔަބައިމީހުންގެ ރުޅިވެރިކަމާއި، ހަސަދަވެރިކަން ފާޅުކުރައްވާނެތެވެ.","",""],["","","","ها أنتم هؤلاء تدعون لتنفقوا في سبيل الله فمنكم من يبخل ومن يبخل فإنما يبخل عن نفسه والله الغني وأنتم الفقراء وإن تتولوا يستبدل قوما غيركم ثم لا يكونوا أمثالكم","އޭ މިތިބަމީހުންނޭވެ! ތިޔަބައިމީހުން ތިޔަތިބީއެވެ. ﷲގެ މަގުގައި ހޭދަކުރުމަށް ތިޔަބައިމީހުންނަށް ގޮވައިލައްވަތެވެ. އެހިނދު، ދަހިވެތިވާ މީހުން ތިޔަބައިމީހުންގެ ތެރެއިންވެއެވެ. އަދި، ދަހިވެތިވާ މީހާ (ދަންނާށެވެ!) ފަހެ، އޭނާ ދަހިވެތިވާކަން ކަށަވަރީ، އޭނާގެ އަމިއްލަ ނަފްސުގެ ފަރާތުންނެވެ. ﷲއީ، ފުދިވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އަދި ފަގީރުންނަކީ ތިޔަބައިމީހުންނެވެ. އަދި ތިޔަބައިމީހުން އެނބުރި ފުރަގަސްދޭނަމަ، ތިޔަބައިމީހުންގެ ބަދަލުގައި ތިޔަބައިމީހުން ނޫންބަޔަކު، އެކަލާނގެ ގެންނަވާހުށްޓެވެ. ދެން، ތިޔަބައިމީހުންފަދަ ބަޔަކު ކަމުގައި އެއުރެން ނުވާނެތެވެ.","",""],["","","","بسم الله الرحمن الرحيم إنا فتحنا لك فتحا مبينا","ފާޅުވެ ބަޔާން ވެގެންވާ ފަތަޙަކުން، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށް ފަތަޙަ ދެއްވީމެވެ.","",""],["","","","ليغفر لك الله ما تقدم من ذنبك وما تأخر ويتم نعمته عليك ويهديك صراطا مستقيما","އެއީ ކަލޭގެފާނުންގެ ކުށްފާފައިގެ ތެރެއިން އިސްވެދިޔަކަންތަކާއި، ފަސްވެދިޔަ ކަންތަކުގެފާފަ، ކަލޭގެފާނަށް ﷲ ފުއްސަވައިދެއްވުމަށްޓަކައެވެ. އަދި އެކަލާނގެ ނިއުމަތް ކަލޭގެފާނުގެ މައްޗަށް ފުރިހަމަކޮށްދެއްވުމަށްޓަކައެވެ. އަދި ސީދާވެގެންވާ ތެދުމަގަށް ކަލޭގެފާނަށް މަގުދެއްކެވުމަށްޓަކައެވެ.","",""],["","","","وينصرك الله نصرا عزيزا","އަދި ގަދަފަދަވެގެންވާ ނަސްރަކުން ކަލޭގެފާނަށް ނަސްރު ދެއްވުމަށްޓަކައެވެ.","",""],["","","","هو الذي أنزل السكينة في قلوب المؤمنين ليزدادوا إيمانا مع إيمانهم ولله جنود السماوات والأرض وكان الله عليما حكيما","އެކަލާނގެއީ، މުއުމިނުންގެ ހިތްތަކަށް ހިތްހަމަޖެހުން ބާވައިލެއްވި ރަސްކަލާނގެއެވެ. އެއީ އެއުރެންގެ އީމާންކަމުގެ މައްޗަށް، އެއުރެންނަށް އީމާން ކަން އިތުރުވުމަށްޓަކައެވެ. އުޑުތަކާއި، ބިމުގެ ލަޝްކަރު މިލްކުވެގެންވަނީ، ﷲއަށެވެ. މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","ليدخل المؤمنين والمؤمنات جنات تجري من تحتها الأنهار خالدين فيها ويكفر عنهم سيئاتهم وكان ذلك عند الله فوزا عظيما","(އެއީ) މުއުމިނު ފިރިހެނުންނާއި، މުއުމިނު އަންހެނުން، އެކަލާނގެ ސުވަރުގެތަކަށް ވެއްދެވުމަށްޓަކައެވެ. އެތާނގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުރެތެވެ. އެތާނގައި، އެއުރެން ދެމިތިބޭގޮތުގައެވެ. އަދި އެއުރެންގެ ކުށްފާފަތައް އެއުރެންގެ ކިބައިން ފުއްސެވުމަށްޓަކައެވެ. އަދި ބޮޑުވެގެންވާ ނަސީބު ލިބުމެއްކަމުގައި ﷲގެ ހަޒުރަތުގައި އެކަންތައްވިއެވެ.","",""],["","","","ويعذب المنافقين والمنافقات والمشركين والمشركات الظانين بالله ظن السوء عليهم دائرة السوء وغضب الله عليهم ولعنهم وأعد لهم جهنم وساءت مصيرا","އަދި މުނާފިގު ފިރިހެނުންނާއި، މުނާފިގު އަންހެނުންނާއި، ޝަރީކުކުރާ ފިރިހެނުންނާއި، ޝަރީކުކުރާ އަންހެނުންނަށް އަޒާބު ދެއްވުމަށްޓަކައެވެ. އެއުރެންނީ، ﷲއާމެދު ނުބައި ހީތައް ކުރާމީހުންނެވެ. ނުބައިގޮތް ދިމާވުންއޮތީ އެއުރެންގެ މައްޗަށެވެ. އަދި ﷲއެއުރެންގެ މައްޗަށް ކޯފާލެއްވިއެވެ. އަދި އެއުރެންނަށް ލައުނަތް ލެއްވިއެވެ. އަދި އެއުރެންނަށްޓަކައި ނަރަކަ ތައްޔާރުކުރެއްވިއެވެ. އެއީ ނުބައިވެގެންވާ ނިމިދިޔުމެކެވެ.","",""],["","","","ولله جنود السماوات والأرض وكان الله عزيزا حكيما","އުޑުތަކާއި، ބިމުގެ ލަޝްކަރުތައް މިލްކުވެގެންވަނީ ﷲއަށެވެ. އަދި ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ކަލަކުކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","إنا أرسلناك شاهدا ومبشرا ونذيرا","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނު ފޮނުއްވީ ހެކިވަނިވި ބޭކަލަކު ކަމުގައްޔާއި (މުއުމިނުންނަށް) އުފާވެރިކަމުގެ ޚަބަރު ދެއްވައި، (ކާފިރުންނަށް) ބިރުވެރިކަމުގެ ޚަބަރު ދެއްވާ ބޭކަލަކު ކަމުގައެވެ.","",""],["","","","لتؤمنوا بالله ورسوله وتعزروه وتوقروه وتسبحوه بكرة وأصيلا","(އެއީ) ތިޔަބައިމީހުން ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް އީމާން ވުމަށްޓަކައެވެ. އަދި އެކަލާނގެއަށް ނަސްރުވެރިވުމަށާއި، އެކަލާނގެއަށް މާތްކޮށްހިތުމަށްޓަކައެވެ. އަދި އެކަލާނގެއަށް ހެނދުނާއި، ހަވީރު ތިޔަބައިމީހުން ތަސްބީހަ ދެންނެވުމަށްޓަކައެވެ.","",""],["","","","إن الذين يبايعونك إنما يبايعون الله يد الله فوق أيديهم فمن نكث فإنما ينكث على نفسه ومن أوفى بما عاهد عليه الله فسيؤتيه أجرا عظيما","ހަމަކަށަވަރުން، ކަލޭގެފާނަށް ބައިޢަތު ހިފާމީހުން ބައިޢަތު ހިފާކަންކަށަވަރީ ﷲއަށެވެ. ﷲގެ އަތްޕުޅުވަނީ، އެއުރެންގެ އަތްތަކަށްވުރެ މަތީގައެވެ. ފަހެ، އަހުދު އުވާލައިފިމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާ އަހުދު އުވައިލާކަންކަށަވަރީ، އޭނާގެ އަމިއްލަ ނަފްސުގެ މައްޗަށެވެ. އަދި އެކަމެއްގެ މައްޗަށް އެމީހަކު ﷲއަށް ވެފައިވާ އަހުދު ފުއްދައިފިމީހާ (ދަންނާށެވެ!) ފަހެ، ﷲ އެމީހަކަށް ބޮޑުވެގެންވާ ދަރުމަ ދެއްވާނެތެވެ.","",""],["","","","سيقول لك المخلفون من الأعراب شغلتنا أموالنا وأهلونا فاستغفر لنا يقولون بألسنتهم ما ليس في قلوبهم قل فمن يملك لكم من الله شيئا إن أراد بكم ضرا أو أراد بكم نفعا بل كان الله بما تعملون خبيرا","އަޢުރާބީންގެ ތެރެއިން ހަނގުރާމަޔަށްނުގޮސް ފަސްޖެހުނުމީހުން ކަލޭގެފާނަށް ދަންނަވާނެތެވެ. ތިމަންމެންގެ މުދާތަކާއި، ތިމަންމެންގެ އަހުލުވެރިން ތިމަންމެން ހަނގުރާމަޔަށް ދިޔުން މަޝްޣޫލު ކޮށްފިއެވެ. ފަހެ، ތިމަންމެންގެ ފާފަފުއްސެވުމަށް ކަލޭގެފާނު އެދިވަޑައިގެންދެއްވާށެވެ! އެއުރެންގެ ހިތްތަކުގައި ނުވާއެއްޗެއް، އެއުރެންގެ ދޫތަކުން ބުނެތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންނަށް ގެއްލުމަކަށް އިރާދަކުރައްވައިފިނަމަ، ނުވަތަ ތިޔަބައިމީހުންނަށް މަންފާއަކަށް އިރާދަކުރައްވައިފިނަމަ، ﷲގެ ހަޒުރަތުން އެއްވެސްކަމެއް މިލްކުވެގެންވަނީ، ތިޔަބައިމީހުންކުރެ ފަހެ، ކާކަށްހެއްޔެވެ؟ އަދި ކިއެއްތަ! ތިޔަބައިމީހުންކުރާ ޢަމަލުތައް މޮޅަށްދެނެވޮޑިގެންވާ ކަލަކުކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","بل ظننتم أن لن ينقلب الرسول والمؤمنون إلى أهليهم أبدا وزين ذلك في قلوبكم وظننتم ظن السوء وكنتم قوما بورا","އަދި ކިއެއްތަ! ތިޔަބައިމީހުން ހީކުރީ ރަސޫލާއާއި، މުއުމިނުން އެއުރެންގެ އަހުލުވެރިންގެ ގާތަށް ދުވަހަކުވެސް އެނބުރިވަޑައި ނުގަންނަވާނެކަމަށެވެ. އަދި ތިޔަބައިމީހުންގެ ހިތްތަކުގައި އެކަން ޒީނަތްތެރިކުރެއްވިއެވެ. އަދި ތިޔަބައިމީހުން ނުބައިހީތައް ހީކުރީމުއެވެ. އަދި ގެއްލި ހަލާކުވެގެންވާ ބަޔަކުކަމުގައި ތިޔަބައިމީހުންވީމުއެވެ.","",""],["","","","ومن لم يؤمن بالله ورسوله فإنا أعتدنا للكافرين سعيرا","އަދި ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް އީމާން ނުވާ މީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކާފިރުންނަށްޓަކައި އަނދައަނދާހުންނަ ނަރަކަ ތައްޔާރުކުރެއްވީމެވެ.","",""],["","","","ولله ملك السماوات والأرض يغفر لمن يشاء ويعذب من يشاء وكان الله غفورا رحيما","އަދި އުޑުތަކާއި، ބިމުގެ ވެރިކަންވަނީ ﷲއަށެވެ. އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ފާފަފުއްސަވަތެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް އަޒާބު ދެއްވަތެވެ. އަދި ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ކަލަކުކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","سيقول المخلفون إذا انطلقتم إلى مغانم لتأخذوها ذرونا نتبعكم يريدون أن يبدلوا كلام الله قل لن تتبعونا كذلكم قال الله من قبل فسيقولون بل تحسدوننا بل كانوا لا يفقهون إلا قليلا","ޣަނީމާ ތަކެއް އަތުލުމަށްޓަކައި، ޣަނީމާ ތަކަކަށް (އެބަހީ: ހަނގުރާމަޔަށް) ތިޔަބައިމީހުން ހިނގައްޖެނަމަ، ހަނގުރާމަޔަށް ނުގޮސް ފަސްޖެހުނުމީހުން ބުނާހުށްޓެވެ. ތިޔަބައިމީހުންގެ ފަހަތުން ތިމަންމެން ދިޔުމަށް ތިމަންމެން ދޫކޮށްލާށެވެ! އެއުރެން އެދެނީ، ﷲގެ ބަސްފުޅު ބަދަލުކުރުމަށެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންމެންގެ ފަހަތުން ތިޔަބައިމީހުން އައިސްގެންނުވާނެއެވެ. މީގެކުރިން ﷲ އަންގަވާފައިވަނީ އެފަދައިންނެވެ. ދެން އެއުރެން ބުނާނެތެވެ. އަދި ކިއެއްތަ! ތިޔަބައިމީހުން ތިމަންމެންނާ ހަސަދަވެރިވަނީއެވެ. އަދި ކިއެއްތަ! ދާދިކުޑަކޮށް މެނުވީ އެއުރެންނަކަށް ނުވިސްނެތެވެ.","",""],["","","","قل للمخلفين من الأعراب ستدعون إلى قوم أولي بأس شديد تقاتلونهم أو يسلمون فإن تطيعوا يؤتكم الله أجرا حسنا وإن تتولوا كما توليتم من قبل يعذبكم عذابا أليما","އަޢުރާބީންގެ ތެރެއިން ހަނގުރާމަޔަށް ނުގޮސް ފަސްޖެހުނުމީހުންނަށް ކަލޭގެފާނު ވިދާޅުވާށެވެ! ގަދަފަދަވެގެންވާ ބާރެއްގެ ވެރިބަޔަކުގެ ގާތަށް ދިޔުމަށް ތިޔަބައިމީހުންނަށް ގޮވައިލައްވާނެތެވެ. ތިޔަބައިމީހުން އެއުރެންނާ ހަނގުރާމަކުރުމަށެވެ. ނުވަތަ އެއުރެން ކިޔަމަންވެ އިސްލާމް ވުމަށެވެ. ފަހެ، ތިޔަބައިމީހުން ކިޔަމަންވާނަމަ، ރިވެތިވެގެންވާ ދަރުމަ ތިޔަބައިމީހުންނަށް ﷲ ދެއްވާނެތެވެ. އަދި މީގެކުރިން ތިޔަބައިމީހުން ފުރަގަސްދިން ފަދައިން ތިޔަބައިމީހުން ފުރަގަސްދޭނަމަ، ވޭންދެނިވި އަޒާބަކުން އެކަލާނގެ ތިޔަބައިމީހުންނަށް އަޒާބު ދެއްވާނެތެވެ.","",""],["","","","ليس على الأعمى حرج ولا على الأعرج حرج ولا على المريض حرج ومن يطع الله ورسوله يدخله جنات تجري من تحتها الأنهار ومن يتول يعذبه عذابا أليما","ކަނުމީހާގެ މައްޗަކަށް ކުށެއްނެތެވެ. އަދި ކޮރުމީހާގެ މައްޗަކަށްވެސް ކުށެއްނެތެވެ. އަދި ބަލިމީހާގެ މައްޗަކަށްވެސް ކުށެއްނުމެނެތްމެއެވެ. ﷲއާއި، އެކަލާނގެ ރަސޫލާއަށް ކިޔަމަންވާމީހާ، އެތާނގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކަށް، އެކަލާނގެ އެމީހާ ވައްދަވާނެތެވެ. އަދި ފުރަގަސްދީފި މީހާޔަށް ވޭންދެނިވި އަޒާބަކުން އެކަލާނގެ އަޒާބު ދެއްވާނެތެވެ.","",""],["","","","لقد رضي الله عن المؤمنين إذ يبايعونك تحت الشجرة فعلم ما في قلوبهم فأنزل السكينة عليهم وأثابهم فتحا قريبا","ހަމަކަށަވަރުން، ގަސްދޮށުގައި އެއުރެން ކަލޭގެފާނަށް ބައިޢަތު ހިފާހިނދު، އެ މުއުމިނު ތަކުންނާމެދު ﷲ ރުހިވޮޑިގެންފިއެވެ. ފަހެ، އެއުރެންގެ ހިތްތަކުގައިވާ ކަންތައް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. ފަހެ، އެކަލާނގެ އެއުރެންގެ މައްޗަށް ހިތްހަމަޖެހުން ބާވައިލައްވައި އަދި ޖަޒާއެއްގެ ގޮތުގައި ގާތްވެގެންވާ ފަތަޙެއް އެއުރެންނަށް ދެއްވިއެވެ.","",""],["","","","ومغانم كثيرة يأخذونها وكان الله عزيزا حكيما","އަދި އެއުރެންނަށް ލިބޭނެ ގިނަ ޣަނީމާ މުދާތައްވެސްމެއެވެ. ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","وعدكم الله مغانم كثيرة تأخذونها فعجل لكم هذه وكف أيدي الناس عنكم ولتكون آية للمؤمنين ويهديكم صراطا مستقيما","ތިޔަބައިމީހުންނަށް ލިބޭނެ ގިނަ ޣަނީމާ މުދާތަކެއް، ތިޔަބައިމީހުންނަށް ﷲ ވައުދުކުރައްވާފައިވެއެވެ. ފަހެ، މިކަންތައް ތިޔަބައިމީހުންނަށް އެކަލާނގެ އަވަސްކޮށްދެއްވިއެވެ. އަދި ތިޔަބައިމީހުންގެ ކިބައިން މީސްތަކުންގެ އަތްތައް (އެބަހީ: އުނދަގޫތައް) ދުރުކުރެއްވިއެވެ. އަދި (މުއުމިނުންނަށް ނަސްރު ލިބޭނެކަމުގެ) ހެތްކެއްކަމުގައި އެކަން ވުމަށްޓަކައެވެ. އަދި ތިޔަބައިމީހުންނަށް ސީދާވެގެންވާ ތެދުމަގަކަށް މަގުދެއްކެވުމަށްޓަކައެވެ.","",""],["","","","وأخرى لم تقدروا عليها قد أحاط الله بها وكان الله على كل شيء قديرا","އަދި އެކަމުގެ މައްޗަށް ތިޔަބައިމީހުން ކުޅަދާނަވެގެންނުވާ އެހެންކަމެއްވެއެވެ. ހަމަކަށަވަރުން، ﷲ އެކަން ދެނެވޮޑިގެންވެއެވެ. ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ކަލަކުކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","ولو قاتلكم الذين كفروا لولوا الأدبار ثم لا يجدون وليا ولا نصيرا","ކާފިރު ވިމީހުން، ތިޔަބައިމީހުންނާ ހަނގުރާމަކުރިނަމަ، އެއުރެން ފުރަގަސްދީ އެނބުރި ހިނގައްޖައީސްކަން ކަށަވަރެވެ. ދެން އެއުރެންނަކަށް އެހީތެރިޔަކުވެސް، އަދި ނަސްރުވެރިޔަކުވެސް ނުފެންނާނެތެވެ.","",""],["","","","سنة الله التي قد خلت من قبل ولن تجد لسنة الله تبديلا","(އެއީ) މީގެކުރިންވެސް ﷲ އެކަލާނގެ (އަޅުތަކުންނާމެދު) ކަންހިންގަވާފައިވާ ގޮތެވެ. އަދި ﷲ ކަންހިންގަވާގޮތަށް ބަދަލެއް އަންނާތީ ކަލޭގެފާނަކަށް ފެނިވަޑައެއް ނުގަންނަވާނެތެވެ.","",""],["","","","وهو الذي كف أيديهم عنكم وأيديكم عنهم ببطن مكة من بعد أن أظفركم عليهم وكان الله بما تعملون بصيرا","ތިޔަބައިމީހުންގެ ކިބައިން، އެއުރެންގެ އަތްތައް (އެބަހީ: އުނދަގޫތައް) ދުރުކުރެއްވީ އެކަލާނގެއެވެ. އަދި މައްކާގެ ތެރޭގައި، އެއުރެންގެ މައްޗަށް ތިޔަބައިމީހުން ބާރުވެރިކުރެއްވުމަށްފަހުގައި، އެއުރެންގެ ކިބައިން ތިޔަބައިމީހުންގެ އަތްތައް (އެބަހީ: ހަނގުރާމަކުރުން) ދުރުކުރެއްވީވެސް އެކަލާނގެއެވެ. ތިޔަބައިމީހުންކުރާ ކަންތައް، މޮޅަށް ބައްލަވާވޮޑިގެންވާ ކަލަކު ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","هم الذين كفروا وصدوكم عن المسجد الحرام والهدي معكوفا أن يبلغ محله ولولا رجال مؤمنون ونساء مؤمنات لم تعلموهم أن تطئوهم فتصيبكم منهم معرة بغير علم ليدخل الله في رحمته من يشاء لو تزيلوا لعذبنا الذين كفروا منهم عذابا أليما","އެއުރެންނީ، ކާފިރުވެ، އަދި ހުރުމަތް ތެރިވެގެންވާ މިސްކިތުން ތިޔަބައިމީހުން އެއްކިބާކުރި މީހުންނެވެ. އަދި ގެފުޅަށް ހަދިޔާކުރެވޭ ތަކެތި، އެތަކެތި ކަތިލަންވާ ހިސާބަށް ދިޔަނުދީ ހިފެހެއްޓި މީހުންނެވެ. އަދި ތިޔަބައިމީހުންނަށް ނޭނގި އެއުރެން ގަތުލުކުރެވިދާފަދަ، (ގޮތެއްގައިތިބި) މުއުމިނު ފިރިހެނުންނާއި، މުއުމިނު އަންހެނުންތަކެއް ނެތްނަމަ (އެ ދަނޑިވަޅުގައި މައްކާ ފަތަޙަކުރެއްވުމުގެ އިޒުނަ ދެއްވީހެވެ.) ފަހެ، އެފަދަގޮތެއް މެދުވެރިވެއްޖެނަމަ، ތިޔަބައިމީހުންނަށް އެނގުމަކާނުލައި، އެއުރެންގެ ސަބަބުން، (އެބަހީ: ގަތުލުކުރެވިދާފަދަ ގޮތެއްގައިތިބި މުއުމިނުންގެ ސަބަބުން) ތިޔަބައިމީހުންނަށް މަލާމާތް ލިބިދާނެތެވެ. އެއީ ﷲ އިރާދަކުރައްވާ މީހަކު އެކަލާނގެ ރަހުމަތްގެތެރެޔަށް ވެއްދެވުމަށްޓަކައެވެ. އެއުރެންނަށް ވަކިވެގެންވާނަމަ، ވޭންދެނިވި އަޒާބަކުން އެއުރެންގެ ތެރެއިން ކާފިރުވި މީހުންނަށް ތިމަންރަސްކަލާނގެ އަޒާބު ދެއްވީމުހެވެ.","",""],["","","","إذ جعل الذين كفروا في قلوبهم الحمية حمية الجاهلية فأنزل الله سكينته على رسوله وعلى المؤمنين وألزمهم كلمة التقوى وكانوا أحق بها وأهلها وكان الله بكل شيء عليما","ކާފިރު ވިމީހުން، އެއުރެންގެ ހިތްތަކުގެ ތެރެޔަށް ބޮޑާކަން ވައްދައިފި ހިނދެވެ. އެއީ ޖާހިލީޒަމާނުގެ ބޮޑާކަމެވެ. ފަހެ، ﷲ، އެކަލާނގެ ރަސޫލާގެ މައްޗަށާއި، މުއުމިނު ތަކުންގެ މައްޗަށް، އެކަލާނގެ ހަޒުރަތުން ހިތްހަމަޖެހުން ބާވައިލެއްވިއެވެ. އަދި ތަގުވާގެ ކަލިމަ، އެއުރެންގެ މައްޗަށް ލާޒިމުކުރެއްވިއެވެ. އެއުރެން އެ ކަލިމަށް ހައްގު ކަން ބޮޑުވެފައި، އަދި އެ ކަލިމަގެ އަހުލުވެރިންކަމުގައިވޫއެވެ. ކޮންމެކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ކަލަކުކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","لقد صدق الله رسوله الرؤيا بالحق لتدخلن المسجد الحرام إن شاء الله آمنين محلقين رءوسكم ومقصرين لا تخافون فعلم ما لم تعلموا فجعل من دون ذلك فتحا قريبا","ހަމަކަށަވަރުން، ﷲ، އެކަލާނގެ ރަސޫލާއަށް ހުވަފެންފުޅު ސީދާކުރައްވައި، ހައްގު ގޮތުގައި ތެދުކޮށްދެއްވިއެވެ. ހަމަކަށަވަރުން، ﷲ އިރާދަކުރެއްވިނަމަ ތިޔަބައިމީހުން އަމާންކަމާއެކުގައި، ހުރުމަތް ތެރިވެގެންވާ މިސްކިތަށް ވަންނާނެކަން ކަށަވަރެވެ. ތިޔަބައިމީހުންގެ ބޯތައް ބާލާ ޙާލުގައި، އަދި ކުރުކޮށް ކޮށާ ޙާލު ގައެވެ. ތިޔަބައިމީހުން ބިރުގަތުމަކާވެސް ނުލައެވެ. ފަހެ، ތިޔަބައިމީހުންނަށް ނޭނގޭކަންތައް އެކަލާނގެ ދެނެވޮޑިގެންވެއެވެ. ފަހެ، އޭގެ ކުރިން ގާތުގައިވާ ފަތަޙެއް އެކަލާނގެ ދެއްވާހުށްޓެވެ.","",""],["","","","هو الذي أرسل رسوله بالهدى ودين الحق ليظهره على الدين كله وكفى بالله شهيدا","އެކަލާނގެއީ، ތެދުމަގާއި، ހައްގު ދީނާއިގެން އެކަލާނގެ ރަސޫލާ ފޮނުއްވި ރަސްކަލާނގެއެވެ. އެއީ އެންމެހާ ދީންތަކުގެ މައްޗަށް، އެ ދީން ފާޅުކުރައްވައި މަތިވެރިކުރެއްވުމަށްޓަކައެވެ. ހެކިވެ ވޮޑިގެންވާ ކަލަކުކަމުގައި ﷲ ފުދެއެވެ.","",""],["","","","محمد رسول الله والذين معه أشداء على الكفار رحماء بينهم تراهم ركعا سجدا يبتغون فضلا من الله ورضوانا سيماهم في وجوههم من أثر السجود ذلك مثلهم في التوراة ومثلهم في الإنجيل كزرع أخرج شطأه فآزره فاستغلظ فاستوى على سوقه يعجب الزراع ليغيظ بهم الكفار وعد الله الذين آمنوا وعملوا الصالحات منهم مغفرة وأجرا عظيما","މުޙައްމަދުގެފާނީ، ﷲގެ ރަސޫލާއެވެ. އަދި އެކަލޭގެފާނުގެ އަރިހުގައިވާ މީހުންނީ، ކާފިރުންގެ މައްޗަށް ގަދަފަދަވެގެންވާ ބަޔެކެވެ. އެއުރެންގެ މެދުގައި، އޯގާވެރި ރަހުމަތް ތެރިބަޔެކެވެ. ﷲގެ ހަޒުރަތުން ފަޟްލު ވަންތަވެރިކަމާއި، ރުއްސެވުން އެދޭ ޙާލު، ރުކޫއު ކޮށް ސަޖިދަ ކޮށްއުޅޭ ބަޔަކުކަމުގައި، ކަލޭގެފާނު އެއުރެން ދެކެވަޑައިގަންނަވާނޫއެވެ. ސަޖިދަގެ އަޘަރުން، އެއުރެންގެ އަލާމަތެއުރެންގެ މޫނުތަކުގައިވެއެވެ. އެއީ ތައުރާތު ގައިވާ، އެއުރެންގެ މިސާލެވެ. އަދި އިންޖީލު ގައިވާ، އެއުރެންގެ މިސާލު އޭގެ ކުދިނިރުތައް ފަޅުވާފައިވާ ގޮވާމެއްފަދައެވެ. ދެން އެ ގޮވާންގަސްތަކަށް ގަދަކަންދިނެވެ. ދެން އެ ގޮވާންގަސްތައް ފަލަވެ، އޭގެތަނޑުތަކުގެ މައްޗަށް ސީދާވެ ހެދެމުންދެއެވެ. ގޮވާންކުރާ ދަނޑުވެރިން އަޖާއިބު ކޮށް ހައިރާންކުރުވަމުންނެވެ. އެއުރެންދެކެ، ކާފިރުން ރުޅިއެރުވުމަށްޓަކައެވެ. އެއުރެންގެ ތެރެއިން އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަމީހުންނަށް ފާފަފުއްސެވުމަކާއި، ބޮޑުވެގެންވާ ދަރުމައެއް ދެއްވުމަށް ﷲ ވައުދުކުރައްވާފައިވެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم يا أيها الذين آمنوا لا تقدموا بين يدي الله ورسوله واتقوا الله إن الله سميع عليم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ﷲއާއި، އެކަލާނގެ ރަސޫލާގެ ހަޒުރަތުގައި ތިޔަބައިމީހުން (އެއްވެސްކަމެއްގައި) އިސްވެނުގަންނާށެވެ! އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","يا أيها الذين آمنوا لا ترفعوا أصواتكم فوق صوت النبي ولا تجهروا له بالقول كجهر بعضكم لبعض أن تحبط أعمالكم وأنتم لا تشعرون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ނަބިއްޔާގެ އަޑުފުޅުގެ މައްޗަށް ތިޔަބައިމީހުންގެ އަޑުތައް ނޫފުލާށެވެ! އަދި ތިޔަބައިމީހުން އެއްބަޔަކު އަނެއްބަޔަކަށް ގަދައަޑުން ވާހަކަދައްކާފަދައިން އެކަލޭގެފާނަށް ގަދައަޑުން ބަސްނުދަންނަވާށެވެ! (އެއީ) ތިޔަބައިމީހުންނަށް ނޭނގިތިއްބައި، ތިޔަބައިމީހުންގެ ޢަމަލުތައް ބާތިލު ވެދާނެތީއެވެ.","",""],["","","","إن الذين يغضون أصواتهم عند رسول الله أولئك الذين امتحن الله قلوبهم للتقوى لهم مغفرة وأجر عظيم","ހަމަކަށަވަރުން، ﷲގެ ރަސޫލާގެ އަރިހުގައި އެއުރެންގެ އަޑު މަޑުކުރާ މީހުންނީ އެއުރެންގެ ހިތްތައް ﷲ، އިމްތިހާނުކުރައްވައި، ތަގުވާވެރިވުމަށް ފަހިކޮށްދެއްވި މީހުންނެވެ. އެއުރެންނަށް ފާފަފުއްސެވުމަކާއި، ބޮޑުވެގެންވާ ދަރުމައެއްހުށްޓެވެ.","",""],["","","","إن الذين ينادونك من وراء الحجرات أكثرهم لا يعقلون","ހަމަކަށަވަރުން، (ކަލޭގެފާނުގެ) ކޮޓަރިކޮޅުތަކުގެ ބޭރުން ކަލޭގެފާނަށް ގޮވައި ދަންނަވާ މީހުންކުރެ ގިނަމީހުންނަކަށް ނުވިސްނެތެވެ.","",""],["","","","ولو أنهم صبروا حتى تخرج إليهم لكان خيرا لهم والله غفور رحيم","އަދި ކަލޭގެފާނު އެއުރެންގެގާތަށް ނުކުމެވަޑައިގަންނަވަންދެން އެއުރެން ކެތްކުރިނަމަ، އެގޮތް އެއުރެންނަށް މާހެޔޮކަން ބޮޑުވީސްކަން ކަށަވަރެވެ. ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","يا أيها الذين آمنوا إن جاءكم فاسق بنبإ فتبينوا أن تصيبوا قوما بجهالة فتصبحوا على ما فعلتم نادمين","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެގާތަށް ފާސިގަކު ޚަބަރަކާއިގެން އަތުވެއްޖެނަމަ، އޭގެ ދޮގުތެދުބަލައި، ހަގީގަތް ހޯދާށެވެ! (އެއީ) ނޭނގިތިބެ، ތިޔަބައިމީހުންނަށް ބަޔަކަށް ގެއްލުންދެވިދާނެތީއެވެ. ފަހެ، އެހެންވެއްޖެނަމަ، ތިޔަބައިމީހުން ކުރިކަންތަކުގެ މައްޗަށް ހިތާމަކުރާ ބަޔަކުކަމުގައި ތިޔަބައިމީހުން ވެދާނެތެވެ.","",""],["","","","واعلموا أن فيكم رسول الله لو يطيعكم في كثير من الأمر لعنتم ولكن الله حبب إليكم الإيمان وزينه في قلوبكم وكره إليكم الكفر والفسوق والعصيان أولئك هم الراشدون","އަދި ތިޔަބައިމީހުންގެ ތެރޭގައި ﷲގެ ރަސޫލާ ހުންނެވިކަން ތިޔަބައިމީހުން ދަންނާށެވެ! ކަންތައްތަކުގެ ތެރެއިން ގިނަކަންތަކުގައި އެކަލޭގެފާނު ތިޔަބައިމީހުންނަށް ކިޔަމަންވެވަޑައިގަންނަވާނަމަ، ތިޔަބައިމީހުންނަށް ގެއްލުން ލިބިއްޖައީހެވެ. އަދި އެހެނެއްކަމަކު ﷲ، ތިޔަބައިމީހުން އީމާންކަމަށް ލޯބިޖައްސަވައި، ތިޔަބައިމީހުންގެ ހިތްތަކުގައި އެ އީމާން ކަން ޒީނަތްތެރިކުރެއްވިއެވެ. އަދި ކާފިރުކަމާއި، ފާސިގުކަމާއި، އުރެދުމަށް ތިޔަބައިމީހުން ނުރުހުންތެރިކުރެއްވިއެވެ. އެއުރެންނީ، ހަމަ ތެދުމަގު ލިބިގެންވާ މީހުންނެވެ.","",""],["","","","فضلا من الله ونعمة والله عليم حكيم","(އެއީ) ﷲގެ ހަޒުރަތު ންވާ ފަޟްލު ވަންތަވެރިކަމަކާއި، ނިއުމަތެކެވެ. ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وإن طائفتان من المؤمنين اقتتلوا فأصلحوا بينهما فإن بغت إحداهما على الأخرى فقاتلوا التي تبغي حتى تفيء إلى أمر الله فإن فاءت فأصلحوا بينهما بالعدل وأقسطوا إن الله يحب المقسطين","މުއުމިނުންގެ ދެބަޔަކު ތަޅައިފޮޅައިގެންފިނަމަ، ފަހެ، އެ ދެބައިމީހުންގެ ދެމެދު ތިޔަބައިމީހުން ސުލްހަކުރާށެވެ! އޭގެތެރެއިން އެއްބަޔަކު އަނެއްބަޔަކަށް ބަޣާވާތް ކޮށްފިނަމަ، އެ ބަޣާވާތްކުރިމީހުން ﷲގެ އަމުރު ފުޅަށް ރުޖޫއަ ވެއްޖައުމަށްދާނދެން އެއުރެންނާ ހަނގުރާމަކުރާށެވެ! ފަހެ، އެއުރެން ރުޖޫއަ ވެއްޖެނަމަ، ފަހެ، ޢަދުލުވެރިގޮތުން އެދެބައިމީހުންގެ ދެމެދު ސުލްހަކުރާށެވެ! އަދި ތިޔަބައިމީހުން ޢަދުލުވެރިވާށެވެ! ހަމަކަށަވަރުން، ޢަދުލުވެރިންދެކެ ﷲ ލޯބިވެވޮޑިގެންވެތެވެ.","",""],["","","","إنما المؤمنون إخوة فأصلحوا بين أخويكم واتقوا الله لعلكم ترحمون","މުއުމިނުން ވާކަންކަށަވަރީ، އަޚުންތަކެއް ކަމުގައެވެ. ފަހެ، ތިޔަބައިމީހުންގެ ދެ އަޚުން ދެމެދު ތިޔަބައިމީހުން ސުލްހަކުރާށެވެ! އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! (އެއީ) ތިޔަބައިމީހުންނަށް ރަހުމަތް ލެއްވުމަށްޓަކައެވެ.","",""],["","","","يا أيها الذين آمنوا لا يسخر قوم من قوم عسى أن يكونوا خيرا منهم ولا نساء من نساء عسى أن يكن خيرا منهن ولا تلمزوا أنفسكم ولا تنابزوا بالألقاب بئس الاسم الفسوق بعد الإيمان ومن لم يتب فأولئك هم الظالمون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ފިރިހެނުންގެ އެއްބަޔަކު އަނެއްބަޔަކަށް ފުރައްސާރަ ނުކުރާހުށިކަމެވެ! އެހެނީ އެ ފުރައްސާރަކުރި މީހުންނަށްވުރެ، އެ ފުރައްސާރަކުރެވުނު މީހުން މާހެޔޮކަން ބޮޑުކަމުގައި ވެދާނެތެވެ. އަދި އަންހެނުންގެ އެއްބަޔަކު އަނެއްބަޔަކަށް ފުރައްސާރަ ނުކުރާހުށިކަމެވެ! އެހެނީ އެ ފުރައްސާރަކުރި މީހުންނަށްވުރެ، އެފުރައްސާރަކުރެވުނު މީހުން މާހެޔޮކަންބޮޑުކަމުގައި ވެދާނެތެވެ. އަދި ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތަކަށް އައިބު ނުކިޔާށެވެ! (އެބަހީ: އެކަކު އަނެކަކަށް އައިބު ނުކިޔާށެވެ!) އަދި އެއްބަޔަކު އަނެއްބަޔަކަށް ނުރުހޭކަހަލަ ލަގަބު ތަކުން ނުގޮވާށެވެ! އީމާން ވުމަށްފަހު ފާސިގު ވުމުގެ ނަން ލިބުމަކީ، ހާދަހާ ނުބައިވެގެންވާ ކަމެކެވެ. އަދި (އެކަންތަކުން) ތައުބާ ނުވި މީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ، ހަމަ އަނިޔާވެރިންނެވެ.","",""],["","","","يا أيها الذين آمنوا اجتنبوا كثيرا من الظن إن بعض الظن إثم ولا تجسسوا ولا يغتب بعضكم بعضا أيحب أحدكم أن يأكل لحم أخيه ميتا فكرهتموه واتقوا الله إن الله تواب رحيم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ހީގެތެރެއިން ގިނަކަންތަކާ ދުރުވެގަންނާށެވެ! ހަމަކަށަވަރުން، ބައެއް ހީއަކީ ފާފައެކެވެ. އަދި ތިޔަބައިމީހުން އެކަކު އަނެކަކަށް ޖާސޫސް ނުކުރާށެވެ! އަދި އެއްބަޔަކު އަނެއްބަޔަކަށް ޣީބަ ނުބުނާށެވެ! ތިޔަބައިމީހުންކުރެ އެކަކުވެސް އޭނާގެ އަޚާގެ މަސް މުޅަކޮށް ކެއުމަށް ލޯބިކުރާނެ ހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުން އެކަމަކަށް ނުރުހޭނޫއެވެ. އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ތައުބާ ގަބޫލުކުރައްވާ ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","يا أيها الناس إنا خلقناكم من ذكر وأنثى وجعلناكم شعوبا وقبائل لتعارفوا إن أكرمكم عند الله أتقاكم إن الله عليم خبير","އޭ މީސްތަކުންނޭވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން ހެއްދެވީ، ފިރިހެނަކާއި، އަންހެނެއްގެ ކިބައިންނެވެ. (އެބަހީ: އާދަމުގެފާނާއި، ޙައްވާގެފާނުގެ ކިބައިންނެވެ.) އަދި ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން ތަފާތު ގައުމު ތަކަށާއި، ގަބީލާތަކަށް ލެއްވީ، ތިޔަބައިމީހުން އެއްބަޔަކު އަނެއްބަޔަކަށް ތަޢާރަފް ވުމަށްޓަކައެވެ. ހަމަކަށަވަރުން، ﷲގެ ހަޒުރަތުގައި ތިޔަބައިމީހުންކުރެ އެންމެ މާތްކަންބޮޑީ، ތިޔަބައިމީހުންކުރެ އެންމެ ތަގުވާވެރި މީހާއެވެ. ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޚައިބަރުވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","قالت الأعراب آمنا قل لم تؤمنوا ولكن قولوا أسلمنا ولما يدخل الإيمان في قلوبكم وإن تطيعوا الله ورسوله لا يلتكم من أعمالكم شيئا إن الله غفور رحيم","އަޢުރާބީން ބުނޫއެވެ. ތިމަންމެން އީމާން ވެއްޖައީމުއެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން އީމާނެއް ނުވަމުއެވެ. އެހެނެއްކަމަކު، ތިމަންމެން ކިޔަމަންވެއްޖައީމުއޭ ބުނާށެވެ! ތިޔަބައިމީހުންގެ ހިތްތަކުގެ ތެރެޔަކަށް އީމާންކަމެއް އަދި ނުވަދެތެވެ. އަދި ތިޔަބައިމީހުން ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް ކިޔަމަންވާނަމަ، ތިޔަބައިމީހުންގެ ޢަމަލު ތަކުން (އެބަހީ: އޭގެ ސަވާބުން) ތިޔަބައިމީހުންނަކަށް އެއްވެސް އެއްޗެއް އުނި ނުކުރައްވާހުށްޓެވެ. ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","إنما المؤمنون الذين آمنوا بالله ورسوله ثم لم يرتابوا وجاهدوا بأموالهم وأنفسهم في سبيل الله أولئك هم الصادقون","މުއުމިނުން ކަމުގައިވާކަން ކަށަވަރީ، ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް އީމާންވެ، ދެން (އެ އީމާންކަމާމެދު) ޝައްކު ނުކުރާ މީހުންނެވެ. އަދި އެއުރެންގެ މުދާތަކާއި، ނަފްސު ތަކުން ﷲގެ މަގުގައި ޖިހާދުކުރިމީހުންނެވެ. އެއުރެންނީ، ހަމަ ތެދުވެރިންނެވެ.","",""],["","","","قل أتعلمون الله بدينكم والله يعلم ما في السماوات وما في الأرض والله بكل شيء عليم","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންތިބީ ކޮން ދީނެއްގައިކަން ﷲއަށް ތިޔަބައިމީހުން އަންގައިދެނީހެއްޔެވެ؟ އުޑުތަކުގައްޔާއި، ބިމުގައިވާހާކަމެއް ﷲ ދެނެވޮޑިގެންވެތެވެ. އަދި ﷲއީ، ކޮންމެކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","يمنون عليك أن أسلموا قل لا تمنوا علي إسلامكم بل الله يمن عليكم أن هداكم للإيمان إن كنتم صادقين","އެއުރެން އިސްލާމް ވީކަމަށް ކަލޭގެފާނަށް އެއުރެން ކަލަގޮވަތެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން އިސްލާމް ވީކަމަށްޓަކައި ތިމަންކަލޭގެފާނަށް ތިޔަބައިމީހުން ކަލަނުގޮވާށެވެ! އަދި ކިއެއްތަ! ތިޔަބައިމީހުންނަށް އީމާންކަމަށް މަގުދެއްކެވިކަމަށްޓަކައި ﷲ، ތިޔަބައިމީހުންގެ މައްޗަށް ދަރުމަވަންތަވެވޮޑިގެންވެތެވެ. (އެއީ) ތިޔަބައިމީހުން ތެދުވެރިން ކަމުގައިވާނަމައެވެ.","",""],["","","","إن الله يعلم غيب السماوات والأرض والله بصير بما تعملون","ހަމަކަށަވަރުން، އުޑުތަކާއި، ބިމުގެ ޣައިބު ދެނެވޮޑިގެންވަނީ، ﷲއެވެ. އަދި ﷲ، ތިޔަބައިމީހުންކުރާ ޢަމަލުތައް މޮޅަށް ބައްލަވާވޮޑިގެންވެތެވެ.","",""],["","","","بسم الله الرحمن الرحيم ق والقرآن المجيد","ق (މި އަކުރުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.) މާތްވެގެންވާ ގުރްއާން ގަންދެއްވައި ވަހީކުރައްވަމެވެ. (ހަމަކަށަވަރުން، އިންޒާރުކުރައްވާ ބޭކަލަކު ކަމުގައި ތިމަންރަސްކަލާނގެ މުޙައްމަދުގެފާނު ފޮނުއްވީމެވެ.)","",""],["","","","بل عجبوا أن جاءهم منذر منهم فقال الكافرون هذا شيء عجيب","އަދި ކިއެއްތަ! އިންޒާރުކުރައްވާ ބޭކަލަކު އެއުރެންގެ ތެރެއިން، އެއުރެންގެ ގާތަށް ވަޑައިގަތްކަމަށްޓަކައި، އެއުރެން ހައިރާން ވޫއެވެ. ފަހެ، ކާފިރުން ބުނޫއެވެ. މިއީ އަޖާއިބު ވާފަދަ ކަމެކެވެ.","",""],["","","","أإذا متنا وكنا ترابا ذلك رجع بعيد","(ތިމަންމެން އަލުން ދިރުމަކަށް ރުޖޫއަ ވާހުށީ) ތިމަންމެން މަރުވެ ވެއްޔަށްވީމާ ހެއްޔެވެ؟ އެއީ ވަރަށްވެސް ދުރު ރުޖޫއަ ވުމެކެވެ.","",""],["","","","قد علمنا ما تنقص الأرض منهم وعندنا كتاب حفيظ","ހަމަކަށަވަރުން، ބިންގަނޑު އެއުރެންގެ ހަށިތަކުން އުނިކުރާ އެއްޗެއް ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގެންވަމެވެ. އަދި ތިމަންރަސްކަލާނގެ ހަޒުރަތުގައި (ހުރިހާ އެއްޗެއް) ރައްކާކުރާ ފޮތެއްވެއެވެ.","",""],["","","","بل كذبوا بالحق لما جاءهم فهم في أمر مريج","އަދި ކިއެއްތަ! އެއުރެންގެ ގާތަށް ހައްގު އައިހިނދު، އެއުރެން އެ ދޮގުކުރޫއެވެ. ފަހެ، އެއުރެންވަނީ، ހަމަޖެހުމެއްނެތް ޙާލަތެއްގެ ތެރޭގައެވެ.","",""],["","","","أفلم ينظروا إلى السماء فوقهم كيف بنيناها وزيناها وما لها من فروج","ފަހެ، އެއުރެންނާ ދިމާ މަތީގައިވާ އުޑު، ތިމަންރަސްކަލާނގެ ހައްދަވައި، އެ އުޑު ޒީނަތްތެރި ކުރައްވާފައިވަނީ ކޮންފަދައަކުންކަން އެއުރެން ނުބަލަނީ ހެއްޔެވެ؟ އަދި އެ އުޑު ފަޅަފަޅައިގެން ގޮސްފައެއްވެސް ނުވެއެވެ.","",""],["","","","والأرض مددناها وألقينا فيها رواسي وأنبتنا فيها من كل زوج بهيج","އަދި ތިމަންރަސްކަލާނގެ ބިން ފަތުރުއްވައި، އެ ބިމުގައި ސާބިތުވެގެންވާ ފަރުބަދަތައް ލެއްވީމެވެ. އަދި އެ ބިމުގައި ހިތްއުފާކުރުވަނިވި ހުރިހާ ބާވަތެއްގެ ގަސް ފެޅުއްވީމެވެ.","",""],["","","","تبصرة وذكرى لكل عبد منيب","(އެއީ ތިމަންރަސްކަލާނގެއަށް) ތައުބާވާ ކޮންމެ އަޅަކަށް އިބްރަތެއް ކަމުގައްޔާއި، ހަނދާންކޮށްދިނުމެއް ކަމުގައެވެ.","",""],["","","","ونزلنا من السماء ماء مباركا فأنبتنا به جنات وحب الحصيد","އަދި ތިމަންރަސްކަލާނގެ އުޑުން ބަރަކާތް ތެރި ފެނެއް ވެއްސެވީމެވެ. އަދި އެއިން ބަގީޗާތަކާއި، ކަނޑައި ރައްކާކުރެވޭ ގޮވާމުގެ އޮށްޓަރު ފެޅުއްވީމެވެ.","",""],["","","","والنخل باسقات لها طلع نضيد","އަދި މަތިމައްޗަށްހުރި އެތްތައް ނުކުމެފައިވާ ދިގު ކަދުރުރުއްތައްވެސް (ފެޅުއްވީމެވެ.)","",""],["","","","رزقا للعباد وأحيينا به بلدة ميتا كذلك الخروج","(އެއީ) އަޅުތަކުންނަށް ރޯއްޖެއް ކަމުގައެވެ. އަދި މަރުވެފައިވާ ރަށެއް އެ ފެނުން، ތިމަންރަސްކަލާނގެ ދިރުއްވީމެވެ. (ކަށްވަޅުތަކުން) ނުކުތުންވެސް ވަނީ އެފަދައިންނެވެ.","",""],["","","","كذبت قبلهم قوم نوح وأصحاب الرس وثمود","އެއުރެންގެ ކުރީގައި، ނޫޙުގެފާނުގެ ގައުމުގެމީހުންނާއި، ރައްސުގެ އެކުވެރިންނާއި، ޘަމޫދު ބާގައިމީހުން (ރަސޫލުން) ދޮގުކުރޫއެވެ.","",""],["","","","وعاد وفرعون وإخوان لوط","އަދި ޢާދު ބާގައިމީހުންނާއި، ފިރްޢައުނާއި ލޫޠުގެފާނުގެ އިޚްވާނު ންވެސް (ދޮގުކުރޫއެވެ.)","",""],["","","","وأصحاب الأيكة وقوم تبع كل كذب الرسل فحق وعيد","އަދި އަލްއައިކަތުގެ އެކުވެރިންނާއި، ތުއްބަޢުގެ ގައުމުގެމީހުންނާއި، އެހުރިހާ އެންމެންވެސް ރަސޫލުން ދޮގުކުރޫއެވެ. ތިމަންރަސްކަލާނގެ ވަޢީދު (އެއުރެންނަށް) ހައްގު ވެއްޖެއެވެ.","",""],["","","","أفعيينا بالخلق الأول بل هم في لبس من خلق جديد","ފަހެ، ފުރަތަމަފަހަރު އުފެއްދެވުމަށް، ތިމަންރަސްކަލާނގެ ނުކުޅެދިވޮޑިގެން ވީންހެއްޔެވެ؟ (ވީމާ، ދެވަނަފަހަރަށް އަލުން އިއާދަކުރެއްވުމަށް ނުކުޅެދިވޮޑިގެން ވާނެހެއްޔެވެ؟) އަދި ކިއެއްތަ! އެއުރެންވަނީ އަލުން ހެއްދެވުމާމެދު ޝައްކެއްގައެވެ.","",""],["","","","ولقد خلقنا الإنسان ونعلم ما توسوس به نفسه ونحن أقرب إليه من حبل الوريد","އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އިންސާނާ ހެއްދެވީމެވެ. އަދި އޭނާގެ ނަފްސު އޭނާޔަށް ވަސްވާސްދޭ ކަންތައް ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގެންވަމެވެ. އަދި އޭނާގެ ކަނދުރާގެ މައިނާރަށްވުރެވެސް ތިމަންރަސްކަލާނގެ އޭނާޔާ ކުއްތަންވެވޮޑިގަތުން ބޮޑެވެ.","",""],["","","","إذ يتلقى المتلقيان عن اليمين وعن الشمال قعيد","(އެއީ އޭނާގެ) ކަނާތްފަރާތުގައްޔާއި، ވާތްފަރާތުގައި ތިއްބަވާ ދެ މަލާއިކަތުން (އޭނާ ކުރާ ކަންތަކާއި، ބުނާ ބަސްތައް) ލިޔުއްވާހިނދުގައެވެ.","",""],["","","","ما يلفظ من قول إلا لديه رقيب عتيد","(ކުރާ ޢަމަލުތައް) ބަލަހައްޓަވަން އޭނާގެ ކައިރީގައި ޙާޒިރުުވެ މަލާއިކަތަކުނެތި، އެނާޔަކަށް އެއްވެސް ބަހެއް ނުބުނެވެތެވެ.","",""],["","","","وجاءت سكرة الموت بالحق ذلك ما كنت منه تحيد","އަދި މަރުގެ ސަކަރާތް ހައްގު ގޮތުގައި އަންނަހުށްޓެވެ. އެއީ ތިބާ އެޔަށް ފިލަންއުޅޭ ކަމުގައިވީ މަރެވެ.","",""],["","","","ونفخ في الصور ذلك يوم الوعيد","(އަލުން ދިރުއްވުމަށް) ތާޅަފިލި ފުމެލައްވާނެތެވެ. އެއީ (ކާފިރުންނަށް އަޒާބުގެ) ވަޢީދު އަންނަ ދުވަހެވެ.","",""],["","","","وجاءت كل نفس معها سائق وشهيد","އަދި (އެދުވަހު) ކޮންމެ ނަފްސެއް (މަހުޝަރު ބިމަށް) އަންނަހުށީ، އޭނާޔާ އެކުގައި ލަވައި ގެންދާނޭ މަލާއިކަތަކާއި، ހެތްކަކުވާ ޙާލު ގައެވެ.","",""],["","","","لقد كنت في غفلة من هذا فكشفنا عنك غطاءك فبصرك اليوم حديد","ހަމަކަށަވަރުން، ތިބާ މިކަންތަކާމެދު ޣާފިލުކަމެއްގައިވީމުއެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ ތިބާގެ ކިބައިން ޣާފިލުކަމުގެ ފަރުދާ ކަޝްފުކުރެއްވީމެވެ. ފަހެ، މިއަދު ތިބާގެ ލޮލަކީ ތޫނު ލޮލެކެވެ.","",""],["","","","وقال قرينه هذا ما لدي عتيد","އަދި އޭނާޔާ ޙަވާލު ވެފައިވާ މަލާއިކަތާ ވިދާޅުވާނެތެވެ. އަހުރެންނާއެކު ޙާޒިރުުކުރައްވާފައިވަނީ އޭނާގެ ޢަމަލުތަކުގެ ފަތެވެ.","",""],["","","","ألقيا في جهنم كل كفار عنيد","(އެ ދެ މަލާއިކަތުންނަށް އަންގަވާނެތެވެ.) ހައްގު އާދެކޮޅުހަދާ، ގޮތްދޫނުކުރާ ކޮންމެ ކާފިރަކު ނަރަކަޔަށް އެއްލަވާށެވެ!","",""],["","","","مناع للخير معتد مريب","(އެއީ) ހެޔޮކަންތައް މަނާކުރުން ގިނަ އަނިޔާވެރި، ދީނާމެދު ޝައްކުކުރާ ކޮންމެ މީހެކެވެ.","",""],["","","","الذي جعل مع الله إلها آخر فألقياه في العذاب الشديد","އެއީ ﷲއާއެކު އެހެން އިލާހަކު ޝަރީކުކުރި މީހާއެވެ. ފަހެ، ތިޔަ ދެ މަލާއިކަތުން، އޭނާ ގަދަފަދަ އަޒާބުގެ ތެރެޔަށް އެއްލަވާށެވެ!","",""],["","","","قال قرينه ربنا ما أطغيته ولكن كان في ضلال بعيد","އޭނާޔާ އެކުގައިވާ ޝައިތާނާ ބުނާނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އޭނާ މަގުފުރެއްދީ ތިމަންނައެއް ނޫނެވެ. އެހެނެއްކަމަކު، އޭނާވީ ދުރުވެގެންވާ މަގުފުރެދުމެއްގައެވެ.","",""],["","","","قال لا تختصموا لدي وقد قدمت إليكم بالوعيد","އެކަލާނގެ ވަހީކުރައްވާނެތެވެ. ތިމަންރަސްކަލާނގެ ހަޒުރަތުގައި ތިޔަބައިމީހުން ދެބަސްވެ އަރާރުން ނުވާށެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، ތިޔަބައިމީހުންނަށް އަޒާބުގެ ވަޢީދު ވަނީ އިސްކުރައްވާފައެވެ.","",""],["","","","ما يبدل القول لدي وما أنا بظلام للعبيد","ތިމަންރަސްކަލާނގެ ހަޒުރަތުގައި ވަޢީދުގެ ބަސްފުޅު ބަދަލުވުމެއްނެތެވެ. އަދި ތިމަންރަސްކަލާނގެއީ، އަޅުތަކުންނަށް އަނިޔާވެރިވެވޮޑިގެންވާ ކަލަކުކަމުގައި ނުވަމެވެ.","",""],["","","","يوم نقول لجهنم هل امتلأت وتقول هل من مزيد","އެދުވަހަކީ، ތިމަންރަސްކަލާނގެ، ނަރަކަޔަށް، ކަލޭ ފުރިއްޖެހޭ ވަހީކުރައްވާނޭ ދުވަހެވެ. އަދި އެ ނަރަކަ، ދެން އިތުރަކަށް ނެތްތޯއޭ ދަންނަވާނޭ ދުވަހެވެ.","",""],["","","","وأزلفت الجنة للمتقين غير بعيد","އަދި ތަގުވާވެރިންނަށް ސުވަރުގެ، ދުރުނޫން ހިސާބަކަށް ކައިރި ކުރައްވާނެތެވެ.","",""],["","","","هذا ما توعدون لكل أواب حفيظ","(އަދި އަންގަވާނެތެވެ.) މިއީ ތިޔަބައިމީހުންނަށް ވައުދުކުރައްވާ ކަންތަކެވެ. (އެކަންއޮތީ) ﷲގެ ހަޒުރަތަށް ގިނަގިނައިން ރުޖޫއަވާ، އަދި އެކަލާނގެ އަހުދުތަކަށް ރައްކާތެރިވާ ކޮންމެ މީހަކަށެވެ.","",""],["","","","من خشي الرحمن بالغيب وجاء بقلب منيب","(އެއީ) ރަޙްމާންވަންތަ ރަސްކަލާނގެއަށް ޣައިބުގައި ބިރުވެތިވެ، އަދި އެކަލާނގެ ހަޒުރަތަށް ތައުބާވާ ހިތަކާއިގެން އައި (ކޮންމެ) މީހެކެވެ.","",""],["","","","ادخلوها بسلام ذلك يوم الخلود","(ތަގުވާވެރިންނަށް އަންގަވާނެތެވެ.) ތިޔަބައިމީހުން އަމާންކަމާއެކު އެ ސުވަރުގެޔަށް ވަންނާށެވެ! އެއީ އަބަދަށް ދެމިތިބުމުގެ ދުވަހެވެ.","",""],["","","","لهم ما يشاءون فيها ولدينا مزيد","އެ ސުވަރުގޭގައި އެއުރެންނަށް އެއުރެން އެދޭހާ ކަމެއްވެއެވެ. އަދި ތިމަންރަސްކަލާނގެ ހަޒުރަތުގައި އިތުރު ނިއުމަތްތައްވެސް ވެއެވެ.","",""],["","","","وكم أهلكنا قبلهم من قرن هم أشد منهم بطشا فنقبوا في البلاد هل من محيص","އަދި އެއުރެންގެ ކުރިން، ތިމަންރަސްކަލާނގެ ކިތައްކިތައް އުއްމަތް ހަލާކުކުރެއްވިން ހެއްޔެވެ؟ އެއުރެންނަށްވުރެ، އެ އިހުގެ މީހުން ބާރުގެ ގޮތުން މާގަދަފަދައެވެ. ފަހެ، އެއުރެން ރަށްތަކަށް ދަތުރުކޮށް ހޯދައި ބެލިއެވެ. އެއުރެންނަށް ފިލަންދާނެތަނެއް ފެނުނުހެއްޔެވެ؟","",""],["","","","إن في ذلك لذكرى لمن كان له قلب أو ألقى السمع وهو شهيد","ހަމަކަށަވަރުން، ހިތެއްވާ މީހަކަށް، ނުވަތަ ޙާޒިރުު ވެހުރެ ކަނުލައި އަހާމީހަކަށް، އެކަމުގައި ނަސޭހަތާއި އިބްރަތް ވާކަން ކަށަވަރެވެ.","",""],["","","","ولقد خلقنا السماوات والأرض وما بينهما في ستة أيام وما مسنا من لغوب","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އުޑުތަކާއި، ބިމާއި، އެދެމެދުގައިވާހާ ތަކެތި ހަދުވަހުގެ ތެރޭގައި ހެއްދެވީމެވެ. އަދި ތިމަންރަސްކަލާނގެއަށް ވަރުބަލިކަމެއް ލިބިވޮޑިއެއް ނުގަންނަވަތެވެ.","",""],["","","","فاصبر على ما يقولون وسبح بحمد ربك قبل طلوع الشمس وقبل الغروب","ފަހެ، އެއުރެން ދައްކާ ވާހަކަތަކަށް ކަލޭގެފާނު ކެތްކުރައްވާށެވެ! އަދި އިރު އެރުމުގެ ކުރީގައްޔާއި، އޮސްފުހުމުގެ ކުރީގައި، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް، ހަމްދާއެކު ތަސްބީހަ ވިދާޅުވެ، ނަމާދު ކުރައްވާށެވެ!","",""],["","","","ومن الليل فسبحه وأدبار السجود","އަދި ރޭގަނޑުގައި އެކަލާނގެއަށް ތަސްބީހަ ވިދާޅުވެ، ނަމާދު ކުރައްވާށެވެ! އަދި ނަމާދުތަކުގެ ފަހުގައި، ތަސްބީހަ ވިދާޅުވާށެވެ!","",""],["","","","واستمع يوم يناد المناد من مكان قريب","އަދި ކައިރިތަނަކުން ގޮވައިލައްވާ ބޭކަލަކު ގޮވައިލައްވާ ދުވަހު (ރަނގަޅަށް) އަޑުއަހާށެވެ!","",""],["","","","يوم يسمعون الصيحة بالحق ذلك يوم الخروج","(އެއީ) އެއުރެންނަށް (އެބަހީ: ޚަލްގު ތަކުންނަށް) ހައްގު ގޮތުގައި ގަދަފަދަ އަޑު އިވޭނޭ ދުވަހެވެ. (އެއީ ތާޅަފިލީގެ ދެވަނަ ފުމެލެއްވުމުގެ އަޑެވެ.) އެއީ (ކަށްވަޅުތަކުން އެންމެން) ނުކުތުމުގެ ދުވަހެވެ.","",""],["","","","إنا نحن نحيي ونميت وإلينا المصير","ހަމަކަށަވަރުން، ދިރުއްވަނީވެސް، އަދި މަރުގަންނަވަނީވެސް، ހަމަ ތިމަންރަސްކަލާނގެއެވެ. އަދި (އެންމެހާ ތަކެތި) ރުޖޫއަ ވުންވަނީ ތިމަންރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","يوم تشقق الأرض عنهم سراعا ذلك حشر علينا يسير","(އެއީ) އެއުރެންގެ މަތިން ބިންގަނޑު ފަޅަފަޅައިގެންގޮސް އަވަސްއަވަހަށް މަހުޝަރު ބިމަށް އެއުރެން ގެންދަވާ ދުވަހެވެ. އެއީ ތިމަންރަސްކަލާނގެއަށް ދާދިފަސޭހަ އެއްކުރެއްވުމެކެވެ.","",""],["","","","نحن أعلم بما يقولون وما أنت عليهم بجبار فذكر بالقرآن من يخاف وعيد","އެއުރެން (އެބަހީ: ކާފިރުން) ބުނެއުޅޭ ބަސްތައް، ތިމަންރަސްކަލާނގެ މޮޅަށް ދެނެވޮޑިގެންވަމެވެ. އަދި ކަލޭގެފާނަކީ އެއުރެންގެ މައްޗަށް ގަދަކަން ދެއްކެވުމަށް ފޮނުއްވާފައިވާ ބޭކަލެއް ނޫނެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ ވަޢީދަށް ބިރުގަންނަ މީހަކަށް، ކަލޭގެފާނު ގުރްއާނުން ވައުޒާއި ނަސޭހަތް އިއްވަވާށެވެ!","",""],["","","","بسم الله الرحمن الرحيم والذاريات ذروا","ގިނަގިނައިން ހިރަފުސް ބުރުއްސާ ވައިރޯޅިތަކާއި،","",""],["","","","فالحاملات وقرا","ފެންބަރުކައިފައިވާ ވިލާތަކާއި،","",""],["","","","فالجاريات يسرا","ފަސޭހަކޮށް ދުވާ އުޅަނދުފަހަރާއި،","",""],["","","","فالمقسمات أمرا","ކަންތައްތައް ބައްސަވާ މަލާއިކަތްނާއި (މިހުރިހާ ތަކެތި) ގަންދެއްވައި ވަހީކުރައްވަމެވެ.","",""],["","","","إنما توعدون لصادق","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށް ވައުދުކުރައްވާ ކަންތައްތަކަކީ، ހައްގު ތެދުކަން ކަށަވަރެވެ.","",""],["","","","وإن الدين لواقع","އަދި (ތިޔަބައިމީހުންގެ ޢަމަލުތަކަށް) ޖަޒާ ދެއްވުމަކީ، ވާނޭކަމެއްކަން ކަށަވަރެވެ.","",""],["","","","والسماء ذات الحبك","(ތަރިތައް ހިނގާ) މަގުތަކުގެ ވެރި، ފުރިހަމަކަންބޮޑު، އުޑު ގަންދެއްވައި ވަހީކުރައްވަމެވެ.","",""],["","","","إنكم لفي قول مختلف","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންވަނީ (މުޙައްމަދުގެފާނާއި، ގުރްއާނާމެދު) ޚިލާފު ވެގެންވާ ބަސްތަކެއްގެ ތެރޭގައިކަން ކަށަވަރެވެ.","",""],["","","","يؤفك عنه من أفك","އެކަމުން ދުރުކުރައްވާފައިވަނީ (ﷲގެ އިލްމު ފުޅުގައި) ދުރުކުރައްވާފައިވާ މީހެކެވެ.","",""],["","","","قتل الخراصون","ދޮގުހަދާ މީހުންނަށް ލައުނަތް ލައްވާފައިވެއެވެ.","",""],["","","","الذين هم في غمرة ساهون","އެއުރެންނީ ޖާހިލުކަމުގެ ތެރެޔަށް ގެނބި، ޣާފިލު ވެފައިވާ މީހުންނެވެ.","",""],["","","","يسألون أيان يوم الدين","އެއުރެން (ފުރައްސާރައިގެގޮތުގައި) ސުވާލުކުރެތެވެ. ގިޔާމަތް ދުވަސް އަންނާނީ ކޮންއިރަކުން ހެއްޔެވެ؟","",""],["","","","يوم هم على النار يفتنون","(އެއީ) ނަރަކައިގެ އަޒާބަށް އެއުރެން ހުށަހަޅުއްވާނޭ ދުވަހުއެވެ.","",""],["","","","ذوقوا فتنتكم هذا الذي كنتم به تستعجلون","(އެއުރެންނަށް އަންގަވާނެތެވެ.) ތިޔަބައިމީހުންގެ އަޒާބުގެ ރަހަ ލިބިގަންނާށެވެ! މިއީ (ދުނިޔެމަތީގައި) ތިޔަބައިމީހުން އަވަސްވުންއެދި އުޅުނު އަޒާބެވެ.","",""],["","","","إن المتقين في جنات وعيون","ހަމަކަށަވަރުން، ތަގުވާވެރިންވަނީ، ސުވަރުގެތަކާއި، ފެންއާރުތަކުގެ ނިއުމަތް ގައެވެ.","",""],["","","","آخذين ما آتاهم ربهم إنهم كانوا قبل ذلك محسنين","އެއުރެންވަނީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ އެއުރެންނަށް ދެއްވި ސަވާބު ލިބިލިބިއެވެ. ހަމަކަށަވަރުން، އޭގެކުރިން އެއުރެންވީ އިހްސާން ތެރިން ކަމުގައެވެ.","",""],["","","","كانوا قليلا من الليل ما يهجعون","އެއުރެން ނިދައިއުޅުނީ ރޭގަނޑުން ވަރަށްކުޑަ ވަގުތުކޮޅެއްގައެވެ.","",""],["","","","وبالأسحار هم يستغفرون","އަދި އެއުރެން ހާރުދަމުގައި ފާފަފުއްސެވުމަށްއެދި ދުއާކުރެތެވެ.","",""],["","","","وفي أموالهم حق للسائل والمحروم","އަދި ސުވާލު ކޮށް އެދޭ މީހުންނަށާއި، ނިކަމެތި މަޙްރޫމުންނަށް އެއުރެންގެ މުދަލުގައި ހައްގެއްވެއެވެ.","",""],["","","","وفي الأرض آيات للموقنين","ޔަގީންކުރާ ބަޔަކަށް ބިމުގައި (ކުޅަދުންވަންތަކަމުގެ) ހެކިތަކެއްވެއެވެ.","",""],["","","","وفي أنفسكم أفلا تبصرون","އަދި ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސު ތަކުގައިވެސްމެއެވެ. ފަހެ، ތިޔަބައިމީހުން ވިސްނައި ނުބަލަނީ ހެއްޔެވެ؟","",""],["","","","وفي السماء رزقكم وما توعدون","އަދި ތިޔަބައިމީހުންގެ ރޯއްޖާއި، ތިޔަބައިމީހުންނަށް ވައުދުކުރައްވާހާ ކަމެއް (ގެއަމުރުފުޅު) އުޑުގައިވެއެވެ.","",""],["","","","فورب السماء والأرض إنه لحق مثل ما أنكم تنطقون","ފަހެ، އުޑާއި، ބިމުގެ ވެރިރަސްކަލާނގެ ގަންދެއްވައި، ހުވާ ވަހީކުރައްވަމެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ބަސްމޮށޭ ފަދައިން، އެއީ ހަމަ ހައްގު ތެދުކަން ކަށަވަރެވެ.","",""],["","","","هل أتاك حديث ضيف إبراهيم المكرمين","އިބްރާހީމްގެފާނުގެ މާތްވެގެންވާ މެހުމާނުންގެ ވާހަކަ، ކަލޭގެފާނާ ހަމަޔަށް އައިސްފައިވޭތޯއެވެ؟","",""],["","","","إذ دخلوا عليه فقالوا سلاما قال سلام قوم منكرون","އެ މެހުމާނުން އެކަލޭގެފާނުގެ އަރިހަށް ގެންނެވިހިނދު، ސަލާމަން މިހެން ވިދާޅުވެ ސަލާމްކުރެއްވޫއެވެ. ދެން އެކަލޭގެފާނު ސަލާމް މިހެން ވިދާޅުވެ ސަލާމް ރައްދުކުރެއްވިއެވެ. (އަދި ހިތްޕުޅަށް އަރައިވަޑައިގަތެވެ. މިއީ އަހުރެން) ނުދަންނަ ބަޔެކެވެ.","",""],["","","","فراغ إلى أهله فجاء بعجل سمين","ފަހެ، އެކަލޭގެފާނު، އެކަލޭގެފާނުގެ އަހުލުވެރިންގެ ގާތަށް ސިއްރިޔާތުގައި ވަޑައިގަތެވެ. އަދި ރޫފަރަނގަޅު ޅަގެރިއެއް (ފިއްސަވައިގެން) ގެންނެވިއެވެ.","",""],["","","","فقربه إليهم قال ألا تأكلون","ދެން އެ މެހުމާނުންނާއި، އޭތި ކައިރިކޮށްލައްވައި ވިދާޅުވިއެވެ. ތިޔަބައިމީހުން ނުކާނޫހެއްޔެވެ؟","",""],["","","","فأوجس منهم خيفة قالوا لا تخف وبشروه بغلام عليم","ފަހެ، އެކަލޭގެފާނުގެ ހިތްޕުޅަށް އެއުރެންނާމެދު، ބިރުވެރިކަމެއް ވަދެއްޖެއެވެ. އެ މެހުމާނުން ދެންނެވޫއެވެ. ކަލޭގެފާނު ބިރުފުޅުގެންވަޑައިނުގަންނަވާށެވެ! (ތިމަންމެންނީ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ފޮނުއްވި މަލާއިކަތުންނީމުއެވެ.) އަދި އެ މެހުމާނުން އެކަލޭގެފާނަށް އިލްމުވެރި ދަރިކަލަކު ލިބިވަޑައިގަންނަވާނެކަމުގެ އުފާވެރި ޚަބަރު ދެއްވޫއެވެ.","",""],["","","","فأقبلت امرأته في صرة فصكت وجهها وقالت عجوز عقيم","ފަހެ (އެ އުފާވެރި ޚަބަރު އައްސަވައި) އެކަލޭގެފާނުގެ އަނބިކަނބަލުން ހަޅޭއްފުޅުލައްވަމުން ވަޑައިގަތެވެ. އަދި އެކަމަނާގެ މޫނުފުޅުގައި ތަޅުއްވަމުން ވިދާޅުވިއެވެ. (އަހުރެންނީ) ދަރިމައިނުވާ މުސްކުޅިއަކީމެވެ. (އަހުރެންނަށް ދަރިޔަކު ލިބޭނީ ކިހިނަކުން ހެއްޔެވެ؟)","",""],["","","","قالوا كذلك قال ربك إنه هو الحكيم العليم","އެ މަލާއިކަތުން ދެންނެވޫއެވެ. ކަމަނާގެ ވެރިރަސްކަލާނގެ ވަހީކުރެއްވީ އެފަދައިންނެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ޙަކީމްވަންތަ، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","قال فما خطبكم أيها المرسلون","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ ފޮނުއްވާފައިވާ މަލާއިކަތުންނެވެ! ފަހެ، ތިޔަބޭކަލުން ފޮނުއްވީ ކޮންކަމަކާތޯއެވެ؟","",""],["","","","قالوا إنا أرسلنا إلى قوم مجرمين","އެބޭކަލުން ދެންނެވޫއެވެ. ހަމަކަށަވަރުން، ތިމަންމެން ފޮނުއްވާފައިވަނީ، ކުށްވެރި ގައުމެއްގެ މީހުންގެ ގާތަށެވެ.","",""],["","","","لنرسل عليهم حجارة من طين","(އެއީ) އެއުރެންގެ މައްޗަށް މަށީގެ ހިލަ އުއްކެވުމަށްޓަކައެވެ.","",""],["","","","مسومة عند ربك للمسرفين","(އެއީ) އުރެދުމުގައި ހައްދުފަހަނަޅައިފައިވާ މީހުންނަށްޓަކައި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ފާހަގަލައްވާފައިވާ ހިލައެވެ.","",""],["","","","فأخرجنا من كان فيها من المؤمنين","ފަހެ، މުއުމިނުންގެ ތެރެއިން އެރަށުގައިވާހާ ބަޔަކު، ތިމަންރަސްކަލާނގެ ނެރުއްވީމެވެ.","",""],["","","","فما وجدنا فيها غير بيت من المسلمين","ފަހެ، އެރަށުގައި މުސްލިމުންގެ އެންމެ ގެއެއްގެ އަހުލުވެރިން މެނުވީ ތިމަންރަސްކަލާނގެ ދެކެވޮޑިއެއް ނުގަންނަވަމެވެ.","",""],["","","","وتركنا فيها آية للذين يخافون العذاب الأليم","އަދި ވޭންދެނިވި އަޒާބަށް ބިރުގަންނަ ބަޔަކަށްޓަކައި ތިމަންރަސްކަލާނގެ އެރަށުގައި (އެއުރެން ހަލާކުކުރެއްވިކަމުގެ) އަލާމަތެއް ލެއްވީމެވެ.","",""],["","","","وفي موسى إذ أرسلناه إلى فرعون بسلطان مبين","އަދި ފިރްޢައުނުގެ ގާތަށް ފާޅުވެގެންވާ ހުއްޖަތަކާއެކު ތިމަންރަސްކަލާނގެ މޫސާގެފާނު ފޮނުއްވިހިނދު، އެކަލޭގެފާނުގެ ވާހަކައިގައި އިބްރަތެއްވެއެވެ.","",""],["","","","فتولى بركنه وقال ساحر أو مجنون","ފަހެ، އެ ފިރްޢައުނު އޭނާގެ ލަޝްކަރާއެކު، އީމާންކަމުން ދުރުވެ، އެއްކިބާވިއެވެ. އަދި ބުންޏެވެ. (އެކަލޭގެފާނީ) ޖާދޫގަރެކެވެ. ނުވަތަ މޮޔައެކެވެ.","",""],["","","","فأخذناه وجنوده فنبذناهم في اليم وهو مليم","ފަހެ، ތިމަންރަސްކަލާނގެ، އޭނާޔާއި އޭނާގެ ލަޝްކަރު އަތުލައްވައި އެއުރެން ކަނޑަށް އުއްކަވައިލެއްވީމެވެ. (އޭނާ ޣަރަގު ވީ) އޭނާޔަށް މަލާމާތް ލިބޭފަދަ ކަންތައްކޮށްފައިވާ ޙާލު ގައެވެ.","",""],["","","","وفي عاد إذ أرسلنا عليهم الريح العقيم","ޢާދު ބާގައިމީހުންގައިވެސް އިބްރަތެއްވެއެވެ. އެއީ ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް މަންފާއެއް ނެތް ވައި ފޮނުއްވި ހިނދުގައެވެ.","",""],["","","","ما تذر من شيء أتت عليه إلا جعلته كالرميم","އެ ވައިޖެހުނު ކޮންމެ އެއްޗެއް ފުނޑުފުނޑުކޮށް އަޅިޔަށް ހަދައިނުލައެއް ދުލެއް ނުކުރެއެވެ.","",""],["","","","وفي ثمود إذ قيل لهم تمتعوا حتى حين","އަދި ޘަމޫދު ބާގައިމީހުންގައިވެސް އިބްރަތެއްވެއެވެ. އެއީ އެއުރެންނަށް އެންގެވި ހިނދުގައެވެ. ތިޔަބައިމީހުން ކުޑަހިނދުކޮޅަކަށް އަރާމުކޮށް އުޅޭށެވެ!","",""],["","","","فعتوا عن أمر ربهم فأخذتهم الصاعقة وهم ينظرون","ފަހެ، އެއުރެންގެ ވެރިރަސްކަލާނގެ އަމުރު ފުޅާ ޚިލާފުވެ، އެއުރެން ކިބުރުވެރިވޫއެވެ. ދެން އެއުރެން ބަލަބަލައި ތިއްބައި ހޮނުގުގުރި އެއުރެންގައި ހިފިއެވެ.","",""],["","","","فما استطاعوا من قيام وما كانوا منتصرين","ފަހެ، އެއުރެންނަށް ތެދުވުމަކަށްވެސް ކުޅަދާނައެއް ނުވިއެވެ. އަދި ނަސްރު ލިބިގެންވާ ބަޔަކު ކަމުގައިވެސް އެއުރެން ނުވިއެވެ.","",""],["","","","وقوم نوح من قبل إنهم كانوا قوما فاسقين","އަދި އޭގެކުރިން ތިމަންރަސްކަލާނގެ ނޫޙުގެފާނުގެ ގައުމުގެމީހުން ހަލާކުކުރެއްވީމެވެ. ހަމަކަށަވަރުން، ފާސިގު ވެގެންވާ ބަޔަކު ކަމުގައި އެއުރެންވޫއެވެ.","",""],["","","","والسماء بنيناها بأيد وإنا لموسعون","ތިމަންރަސްކަލާނގެ ކުޅަދުންވަންތަކަމުން އުޑު ހެއްދެވީމެވެ. އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެއީ، ތަނަވަސްކުރެއްވުމަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","والأرض فرشناها فنعم الماهدون","އަދި ތިމަންރަސްކަލާނގެ ބިންގަނޑު ފެތުރުއްވީމެވެ. ފަހެ، ތަންމައްޗެއްގެ ގޮތުގައި (ބިންގަނޑު) ފެތުރުއްވި ރަސްކަލާނގެ މޮޅުކަމާއެވެ!","",""],["","","","ومن كل شيء خلقنا زوجين لعلكم تذكرون","ކޮންމެ އެއްޗަކުން ތިމަންރަސްކަލާނގެ އަންހެން ފިރިހެން ދޭތި އުފެއްދެވީމެވެ. (އެއީ) ތިޔަބައިމީހުން ހަނދުމަކުރުމަށްޓަކައެވެ.","",""],["","","","ففروا إلى الله إني لكم منه نذير مبين","ފަހެ، ތިޔަބައިމީހުން ﷲއަށް ކިޔަމަންވުމަށް އަވަސްވެގަންނާށެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނީ، އެކަލާނގެ ހަޒުރަތުން ތިޔަބައިމީހުންގެ ގާތަށް ފޮނުއްވި، ބަޔާން ވެގެންހުރި އިންޒާރުކުރައްވާ ބޭކަލަކީމެވެ.","",""],["","","","ولا تجعلوا مع الله إلها آخر إني لكم منه نذير مبين","އަދި ތިޔަބައިމީހުން ﷲއާއެކު އެހެން އިލާހަކު ނުލާށެވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނީ، އެކަލާނގެ ހަޒުރަތުން ތިޔަބައިމީހުންގެ ގާތަށް ފޮނުއްވި، ބަޔާން ވެގެންހުރި އިންޒާރުކުރައްވާ ބޭކަލަކީމެވެ.","",""],["","","","كذلك ما أتى الذين من قبلهم من رسول إلا قالوا ساحر أو مجنون","އެފަދައިން އެއީ ޖާދޫގަރެކޭ، ނުވަތަ މޮޔައެކޭ އެއުރެން ނުބުނާ އެއްވެސް ރަސޫލަކު، އެއުރެންގެ ކުރީގެ މީހުންގެ ގާތަކަށްވެސް ވަޑައެއްނުގަންނަވައެވެ.","",""],["","","","أتواصوا به بل هم قوم طاغون","އެއުރެން ރަސޫލުން ދޮގުކުރުމަށް އެއްބަޔަކު އަނެއްބަޔަކަށް ވަސިއްޔަތް ކޮށްފައި ވަނީހެއްޔެވެ؟ އަދި ކިއެއްތަ! އެއުރެންނީ ފުރެދުމުގައި ހައްދުފަހަނަޅައިފައިވާ ބަޔެކެވެ.","",""],["","","","فتول عنهم فما أنت بملوم","ފަހެ، ކަލޭގެފާނު އެއުރެންނާ އެއްކިބާވެވަޑައިގަންނަވާށެވެ! ފަހެ، ކަލޭގެފާނަކީ، މަލާމާތް ލިބިގެންވާ ބޭކަލަކު ކަމުގައި ނުވެތެވެ.","",""],["","","","وذكر فإن الذكرى تنفع المؤمنين","ކަލޭގެފާނު ހަނދާންކޮށްދެއްވާށެވެ! ފަހެ، ހަމަކަށަވަރުން، ހަނދާންކޮށްދިނުމަކީ، މުއުމިނުންނަށް މަންފާކުރާނޭ ކަމެކެވެ.","",""],["","","","وما خلقت الجن والإنس إلا ليعبدون","ތިމަންރަސްކަލާނގެއަށް އަޅުކަންކުރުމަށް މެނުވީ، ތިމަންރަސްކަލާނގެ ޖިންނީންނާއި، އިންސީން ނަހައްދަވަމެވެ.","",""],["","","","ما أريد منهم من رزق وما أريد أن يطعمون","އެއުރެންގެ ކިބަޔަކުން ތިމަންރަސްކަލާނގެ ރިޒްގަކަށް އެދިވޮޑިއެއް ނުގަންނަވަމެވެ. އަދި ކާންދިނުމަކަށްވެސް އެދިވޮޑިއެއް ނުގަންނަވަމެވެ.","",""],["","","","إن الله هو الرزاق ذو القوة المتين","ހަމަކަށަވަރުން، ﷲއީ، ރިޒްގު ދެއްވާ، ބާރުވެރިވަންތަ ގަދަފަދަވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","فإن للذين ظلموا ذنوبا مثل ذنوب أصحابهم فلا يستعجلون","ފަހެ، ހަމަކަށަވަރުން، އަނިޔާވެރިވި މީސްތަކުންނަށް އަޒާބުގެ ޙިއްޞާއެއް ހުށްޓެވެ. (އެއީ) އެއުރެންގެ އެކުވެރިން ކަމުގައިވި މީހުންނަށްހުރި އަޒާބަކާ އެއްފަދަ ޙިއްޞާއެކެވެ. ފަހެ، އަޒާބު އަވަސްވުންއެދި ތިމަންރަސްކަލާނގެ ހަޒުރަތަށް އެއުރެން، ނޭދޭހުށިކަމެވެ!","",""],["","","","فويل للذين كفروا من يومهم الذي يوعدون","ފަހެ ކާފިރުވި މީހުންނަށް އެއުރެންނަށް ވައުދުކުރައްވާ ދުވަހުން ގެއްލުމާއި ހަލާކުހުށްޓެވެ.","",""],["","","","بسم الله الرحمن الرحيم والطور","ޠޫރު ފަރުބަދައާއި،","",""],["","","","وكتاب مسطور","ފަތުރައިލެވިފައިވާ ހަމުގައި ލިޔެވިގެންވާ ފޮތާއި،","",""],["","","","في رق منشور","ފަތުރައިލެވިފައިވާ ހަމުގައި ލިޔެވިގެންވާ ފޮތާއި،","",""],["","","","والبيت المعمور","البيت المعمور އާއި (އެބަހީ: އުޑުގައި މަލާއިކަތުން އަޅުކަން ކުރައްވާ ތަނާއި)","",""],["","","","والسقف المرفوع","އުފުލިގެންވާ އުޑާއި،","",""],["","","","والبحر المسجور","ފުރިގެންވާ ކަނޑާއި (މިހުރިހާ ތަކެތި) ގަންދެއްވައި ވަހީކުރައްވަމެވެ.","",""],["","","","إن عذاب ربك لواقع","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އަޒާބަކީ، އަންނާނެ އެއްޗެއްކަން ކަށަވަރެވެ.","",""],["","","","ما له من دافع","އެ އަޒާބު (އެއުރެންގެ ކިބައިން) ދުރުކޮށްދޭނޭ އެއްވެސް ފަރާތެއް ނުވެތެވެ.","",""],["","","","يوم تمور السماء مورا","އެއީ އުޑު، ވަރަށްގަދަޔަށް ގުޑައިގެންދާ ދުވަހެވެ.","",""],["","","","وتسير الجبال سيرا","އަދި ފަރުބަދަތައް (ހުރިތަނުން ނެއްޓި) ހިނގައިގަންނަ ދުވަހެވެ.","",""],["","","","فويل يومئذ للمكذبين","ފަހެ، އެދުވަހުން ދޮގުކުރާ މީހުންނަށް ގެއްލުމާއި، ހަލާކު ހުށްޓެވެ.","",""],["","","","الذين هم في خوض يلعبون","އެއުރެންނީ ހަމަ ބާތިލު ވާހަކައިގައި ކުޅެކުޅެތިބޭ މީހުންނެވެ.","",""],["","","","يوم يدعون إلى نار جهنم دعا","އެދުވަހު ނަރަކައިގެ އަލިފާނުގެ ތެރެޔަށް އެއުރެން ކޮއްޕައި ވައްޓައިލައްވާނެތެވެ.","",""],["","","","هذه النار التي كنتم بها تكذبون","(އަދި އަންގަވާނެތެވެ.) މިއީ ތިޔަބައިމީހުން ދޮގުކޮށްއުޅުނު ނަރަކަޔެވެ.","",""],["","","","أفسحر هذا أم أنتم لا تبصرون","ފަހެ، މިއީވެސް ޖާދޫހެއްޔެވެ؟ ނުވަތަ ތިޔަބައިމީހުންނަށް ނުފެންނަނީ ހެއްޔެވެ؟","",""],["","","","اصلوها فاصبروا أو لا تصبروا سواء عليكم إنما تجزون ما كنتم تعملون","ތިޔަބައިމީހުން އެ ނަރަކަޔަށް ވަންނާށެވެ! އަދި (އެ އަޒާބަށް) ކެތްކުރާށެވެ! ނުވަތަ ކެތްނުކުރާށެވެ! (ކެތްކުރުމާއި ނުކުރުން) ތިޔަބައިމީހުންގެ މައްޗަށް ހަމަހަމަވެގެންވެއެވެ. ތިޔަބައިމީހުންނަށް ޖަޒާލިބޭކަން ކަށަވަރީ، ތިޔަބައިމީހުން ކޮށްއުޅުނު ކަންތަކަށެވެ.","",""],["","","","إن المتقين في جنات ونعيم","ހަމަކަށަވަރުން، ތަގުވާވެރިން ވާހުށީ، ސުވަރުގެތަކެއްގައެވެ. އަދި ބޮޑުވެގެންވާ ނިއުމަތް ގައެވެ.","",""],["","","","فاكهين بما آتاهم ربهم ووقاهم ربهم عذاب الجحيم","(އެއުރެން އެ ސުވަރުގެތަކުގައި ތިބޭހުށީ) އެއުރެންގެ ވެރިރަސްކަލާނގެ އެއުރެންނަށް ދެއްވި ތަކެތިން މީރުކަން ލިބިލިބިއެވެ. އަދި އެއުރެންގެ ވެރިރަސްކަލާނގެ، ނަރަކައިގެ އަޒާބުން އެއުރެން ދިންނެވިއެވެ.","",""],["","","","كلوا واشربوا هنيئا بما كنتم تعملون","(އަދި އަންގަވާނެތެވެ.) ތިޔަބައިމީހުން ކޮށްއުޅުނު ކަންތަކުގެ ސަބަބުން، އަރާމުލިބެނިވިގޮތުގައި ތިޔަބައިމީހުން ކައިބޮއި އުޅޭށެވެ!","",""],["","","","متكئين على سرر مصفوفة وزوجناهم بحور عين","(އެއުރެން ތިބޭނީ) އެތުރިފައިވާ ދާންތަކެއްގެ މަތީގައި ލެނގިލައިގެންވާ ޙާލު ގައެވެ. އަދި ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ޙޫރުލްޢީނުން އަނބިކޮށްދެއްވީމެވެ.","",""],["","","","والذين آمنوا واتبعتهم ذريتهم بإيمان ألحقنا بهم ذريتهم وما ألتناهم من عملهم من شيء كل امرئ بما كسب رهين","އަދި އީމާން ވިމީހުން އެއުރެންގެ ދަރިން އީމާން ވުމާއެކު، އެއުރެންނަށް ތަބާ ވުމުން، އެއުރެންގެ ދަރިންވެސް ތިމަންރަސްކަލާނގެ އެއުރެންނާ އެއްދަރަޖައިގައި (ސުވަރުގޭގައި) ލައްވާހުށީމެވެ. އަދި އެއުރެންގެ ޢަމަލަކުން އެއްވެސް އެއްޗެއް ތިމަންރަސްކަލާނގެ އުންޏެއް ނުކުރައްވާހުށީމެވެ. ކޮންމެމީހަކީވެސް އެމީހަކު ހޯދި ޢަމަލަކަށް ކަނޑައަޅުއްވާފައިވާ ޖަޒާލިބޭނޭ މީހެކެވެ.","",""],["","","","وأمددناهم بفاكهة ولحم مما يشتهون","އަދި އެއުރެން ހިތްއެދޭ މޭވާގެ ބާވަތްތަކާއި، މަހުގެ ބާވަތްތައް ތިމަންރަސްކަލާނގެ އެއުރެންނަށް ދެއްވާހުށީމެވެ.","",""],["","","","يتنازعون فيها كأسا لا لغو فيها ولا تأثيم","އެ ސުވަރުގޭގައި މަސްތުކުރުމެއް، އަދި ފާފަވެރިކުރުމެއްނުވާ، ބުއިމުގެ ތަށިތަކެއް އެކަކު އަނެކަކަށް ދީހަދާނެތެވެ.","",""],["","","","ويطوف عليهم غلمان لهم كأنهم لؤلؤ مكنون","އަދި އެއުރެންނަށް ހާއްސަ ވެފައިވާ ފިރިހެންކުދިން އެއުރެންގެ ޚިދުމަތުގައި ބުރުޖަހާނެތެވެ. އެކުދިން ރައްކާތެރިވެގެންވާ މުތީތަކެއްފަދައެވެ.","",""],["","","","وأقبل بعضهم على بعض يتساءلون","އަދި އެކަކު އަނެކަކާ ސުވާލުކުރަމުން، އެއުރެންގެ އެއްބަޔަކު އަނެއްބަޔެއްގެ ގާތަށް ކުރިމަތިލައި އަންނާނެތެވެ.","",""],["","","","قالوا إنا كنا قبل في أهلنا مشفقين","އެއުރެން ބުނާނެތެވެ. ހަމަކަށަވަރުން، ކުރިން ތިމަންމެން، ތިމަންމެންގެ އަހުލުވެރިންގެ ތެރޭގައި އުޅުނުއިރު (ﷲގެ އަޒާބަށް) ބިރުވެތިވެގެންވީމުއެވެ.","",""],["","","","فمن الله علينا ووقانا عذاب السموم","ދެން ﷲ ތިމަންމެންގެ މައްޗަށް ދަރުމަވަންތަވެވޮޑިގެންނެވިއެވެ. އަދި ނަރަކައިގެ އަޒާބުން ތިމަންމެން ދިންނެވިއެވެ.","",""],["","","","إنا كنا من قبل ندعوه إنه هو البر الرحيم","ހަމަކަށަވަރުން، ކުރިން ތިމަންމެން އެކަލާނގެއަށް އަޅުކަންކޮށް އުޅުނީމުއެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، އިހްސާން ތެރިވަންތަ، ރަޙީމްވަންތަ ކަލާނގެއެވެ.","",""],["","","","فذكر فما أنت بنعمت ربك بكاهن ولا مجنون","ފަހެ، ކަލޭގެފާނު ހަނދާންކޮށްދެއްވުންމަތީ ދެމިހުންނަވާށެވެ! ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ރަހުމަތްފުޅުން ކަލޭގެފާނީ، ކާހިނަކު ކަމުގައިވެސް އަދި މޮޔައަކު ކަމުގައިވެސް ނުވެތެވެ.","",""],["","","","أم يقولون شاعر نتربص به ريب المنون","އަދި ކިއެއްތަ! އެއީ ޝާޢިރު އެކޭ އެއުރެން ބުނަނީހެއްޔެވެ؟ އެ ޝާޢިރު މަރުވެދިޔުމަށް ތިމަންމެން ބަލަބަލައި ތިބެމުއެވެ.","",""],["","","","قل تربصوا فإني معكم من المتربصين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ބަލަބަލައިތިބޭށެވެ! ފަހެ، ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުވެސް ތިޔަބައިމީހުންނާއެކު ބަލަބަލައިތިބޭ މީހުންގެ ތެރެއިން ވަމެވެ.","",""],["","","","أم تأمرهم أحلامهم بهذا أم هم قوم طاغون","އަދި ކިއެއްތަ! އެއުރެންގެ ބުއްދިތައް އެގޮތަށް ބުނުމަށް އެއުރެންނަށް އަމުރުކުރަނީހެއްޔެވެ؟ ނުވަތަ އެއުރެންނީ ވިސްނުމަކާނުލައި ދެކޮޅުހަދާ ބަޔަކީހެއްޔެވެ؟","",""],["","","","أم يقولون تقوله بل لا يؤمنون","އަދި ކިއެއްތަ! އެ ގުރްއާނަކީ، އެކަލޭގެފާނު އަމިއްލަފުޅަށް ހައްދަވައިގެން ވިދާޅުވާ އެއްޗެއްކަމަށް އެއުރެން ބުނެއުޅެނީހެއްޔެވެ؟ އަދި ކިއެއްތަ! އެއުރެން އީމާނެއް ނުވެތެވެ.","",""],["","","","فليأتوا بحديث مثله إن كانوا صادقين","ފަހެ، އެއުރެންނީ، ތެދުބުނާބަޔަކު ކަމުގައިވާނަމަ، އެފަދަ ގުރްއާނަކާއިގެން އައިސްބަލާށެވެ!","",""],["","","","أم خلقوا من غير شيء أم هم الخالقون","އަދި ކިއެއްތަ! ހެއްދެވިފަރާތެއްނެތި އެއުރެން ހެދިގަތީހެއްޔެވެ؟ ނުވަތަ ހެއްދެވި ފަރާތްތަކަކީ، އެއުރެން ހެއްޔެވެ؟","",""],["","","","أم خلقوا السماوات والأرض بل لا يوقنون","އަދި ކިއެއްތަ! އުޑުތަކާއި، ބިން ހެދީ އެއުރެން ހެއްޔެވެ؟ އަދި ކިއެއްތަ! އެއުރެންނީ، އީމާން ނުވާ ބަޔެކެވެ.","",""],["","","","أم عندهم خزائن ربك أم هم المصيطرون","އަދި ކިއެއްތަ! ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ޚަޒާނާތައް އެބައިމީހުންގެ ގާތުގައި ވަނީހެއްޔެވެ؟ ނުވަތަ އެކަންކަމުގެ ބާރު، އެއުރެންނަށް ލިބިގެންވަނީ ހެއްޔެވެ؟","",""],["","","","أم لهم سلم يستمعون فيه فليأت مستمعهم بسلطان مبين","އަދި ކިއެއްތަ! (މަލާއިކަތުން ދައްކަވާ ވާހަކަފުޅު) އެއުރެން އެހުމަށް އެއުރެންނަށް ހަރުގަނޑެއް ވަނީހެއްޔެވެ؟ ފަހެ، އެއުރެންކުރެ އަހާކަމަށްބުނާ މީހާ، ބަޔާންވެގެންވާ ހުއްޖަތެއް ގެނެސްދީބަލާށެވެ!","",""],["","","","أم له البنات ولكم البنون","އަދި ކިއެއްތަ! އެކަލާނގެއަށް އަންހެންދަރިންވެފައި، ފިރިހެންދަރިން، ތިޔަބައިމީހުންނަށް ވަނީހެއްޔެވެ؟","",""],["","","","أم تسألهم أجرا فهم من مغرم مثقلون","އަދި ކިއެއްތަ! އެއުރެންގެ ކިބައިން އުޖޫރައަކަށް ކަލޭގެފާނު އެދިވަޑައިގަންނަވަނީހެއްޔެވެ؟ ފަހެ، އެއުރެން އެ އުޖޫރަ ދޭންޖެހުމުގެ ސަބަބުން އެއުރެންނަށް ބުރަކަމެއް ލިބެނީހެއްޔެވެ؟","",""],["","","","أم عندهم الغيب فهم يكتبون","އަދި ކިއެއްތަ! ފަހެ، އެއުރެން އެއިން ލިޔުމަށް އެއުރެންގެ ގާތުގައި ޣައިބުގެ އިލްމު ވަނީ ހެއްޔެވެ؟","",""],["","","","أم يريدون كيدا فالذين كفروا هم المكيدون","އަދި ކިއެއްތަ! އެއުރެން (ކަލޭގެފާނާމެދު) ކެހިވެރި ރޭވުމެއް ރާވަން އެދެނީހެއްޔެވެ؟ ފަހެ، ކެހިވެރިކަން ރައްދުވާބަޔަކީ ކާފިރުންނެވެ.","",""],["","","","أم لهم إله غير الله سبحان الله عما يشركون","އަދި ކިއެއްތަ! ﷲ ފިޔަވައި އެހެން އިލާހެއް އެއުރެންނަށް ވަނީހެއްޔެވެ؟ އެއުރެން ޝަރީކުކުރާ ތަކެތިން ﷲ ހުސްތާހިރު ވަންތަވެވޮޑިގެންވެއެވެ.","",""],["","","","وإن يروا كسفا من السماء ساقطا يقولوا سحاب مركوم","(އެއުރެންނަށް އަޒާބެއްގެ ގޮތުގައި) އުޑުން ތަންގަނޑެއް ވެއްޓޭތަން އެއުރެންނަށް ފެނިއްޖެނަމަ، މަތިމައްޗަށްހުރި ވިލާތަކެކޭ އެއުރެން ބުނާނެތެވެ.","",""],["","","","فذرهم حتى يلاقوا يومهم الذي فيه يصعقون","ފަހެ، އެއުރެން ހަލާކުވެގެންދާ ދުވަހާ އެއުރެން ބައްދަލުވެއްޖައުމަށް ދާނދެން، ކަލޭގެފާނު އެއުރެން ދޫކޮށްލައްވާށެވެ!","",""],["","","","يوم لا يغني عنهم كيدهم شيئا ولا هم ينصرون","(އެއީ) އެއުރެންގެ މަކަރުވެރި ރޭވުން، އެއުރެންނަށް އެއްވެސްކަމެއް ފުއްދައިނުދޭ، އަދި އެއުރެންނަށް ނަސްރުވެރިކަމެއްވިޔަސް ނުލިބޭ ދުވަހެވެ.","",""],["","","","وإن للذين ظلموا عذابا دون ذلك ولكن أكثرهم لا يعلمون","ހަމަކަށަވަރުން، އަނިޔާވެރިވީ މީހުންނަށް (ދުނިޔޭގެ) އަޒާބުގެ އިތުރަށް އަޒާބު ހުށްޓެވެ. އެހެނެއްކަމަކު އެއުރެންކުރެ ގިނަމީހުން (އެކަމެއް) ނުދަނެތެވެ.","",""],["","","","واصبر لحكم ربك فإنك بأعيننا وسبح بحمد ربك حين تقوم","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހުކުމް ފުޅަށް ކެތްކުރައްވާށެވެ! ފަހެ، ހަމަކަށަވަރުން، ކަލޭގެފާނުވަނީ ތިމަންރަސްކަލާނގެ ބެއްލެވުމުގެ ދަށުގައެވެ. އަދި ކަލޭގެފާނު ތެދުވެވަޑައިގަންނަވާހިނދު ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް ހަމްދާއެކު ތަސްބީހަ ވިދާޅުވާށެވެ!","",""],["","","","ومن الليل فسبحه وإدبار النجوم","އަދި ރޭގަނޑުން ބައެއްގައްޔާއި، ތަރިތައް އޮއްސޭހިނދު، ކަލޭގެފާނު އެކަލާނގެއަށް ތަސްބީހަ ވިދާޅުވާށެވެ!","",""],["","","","بسم الله الرحمن الرحيم والنجم إذا هوى","އޮއްސިގެންދާހިނދު، ތަރި ގަންދެއްވައި ވަހީކުރައްވަމެވެ.","",""],["","","","ما ضل صاحبكم وما غوى","ތިޔަބައިމީހުންގެ އެކުވެރިޔާ (އެބަހީ: މުޙައްމަދުގެފާނު) ހައްގުގެމަގުން އެއްކިބާވެވަޑައެއް ނުގަންނަވައެވެ. އަދި ބާތިލު އިޢުތިގާދެއް ނުކުރައްވައެވެ.","",""],["","","","وما ينطق عن الهوى","އަދި އެކަލޭގެފާނު އަމިއްލަ އެދުންފުޅަކަށް ވާހަކަފުޅެއް ނުމެދައްކަވާމެއެވެ.","",""],["","","","إن هو إلا وحي يوحى","އެއީ އެކަލޭގެފާނަށް އިއްވަވާ ވަހީއެއްކަމުގައި ނޫނީ ނުވެތެވެ.","",""],["","","","علمه شديد القوى","ބާރުގަދަ މަލާއިކަތަކު، އެކަލޭގެފާނަށް އެ (ވަހީ) އުނގަންނައިދެއްވިއެވެ.","",""],["","","","ذو مرة فاستوى","(އެ މަލާއިކަތަކީ) ވިސްނުންތެރިކަމުގެ ވެރިޔެކެވެ. ފަހެ، އެ މަލާއިކަތާ އެކަލޭގެފާނުގެ އަޞްލު ޞޫރަގައި ގާއިމު ވެވަޑައިގެން ހުންނެވިއެވެ.","",""],["","","","وهو بالأفق الأعلى","(އެހިނދު) އެ މަލާއިކަތާ ވަނީ، އެންމެމަތީ އުދަރެހުގައެވެ.","",""],["","","","ثم دنا فتدلى","ދެން އެ މަލާއިކަތާ (ރަސޫލާއާ) އަރިސްވެވަޑައިގަތެވެ. ދެން އެއަށްވުރެވެސް އަރިސްވެވަޑައިގަތެވެ.","",""],["","","","فكان قاب قوسين أو أدنى","އެ އަރިސްވުންވީ، ދެ ގައުސްގެ މިންވަރަށެވެ. (އެބަހީ: ދެ ދުނިދަނޑީގެ މިންވަރަށެވެ.) ނުވަތަ އެއަށްވުރެވެސް އަރިހަށެވެ.","",""],["","","","فأوحى إلى عبده ما أوحى","ދެން (ﷲ) އެކަލާނގެ އަޅާއަށް ވަހީކުރެއްވި އެއްޗެއް ވަހީކުރެއްވިއެވެ. (އެބަހީ: މަތިވެރިވެގެންވާ ވަހީ ބަސްފުޅުތަކެއް އެކަލޭގެފާނަށް އިއްވެވިއެވެ.)","",""],["","","","ما كذب الفؤاد ما رأى","އެކަލޭގެފާނު ދެކެވަޑައިގެންނެވި ކަންތަކާމެދު (އެކަލޭގެފާނުންގެ) ހިތްޕުޅު އިންކާރެއް ނުކުރައްވަތެވެ.","",""],["","","","أفتمارونه على ما يرى","އެކަލޭގެފާނު ދެކެވަޑައިގަންނަވާ ކަންތަކާމެދު، ތިޔަބައިމީހުން އެކަލޭގެފާނާ ޖަދަލުކުރަނީ ހެއްޔެވެ؟","",""],["","","","ولقد رآه نزلة أخرى","ހަމަކަށަވަރުން، އެކަލޭގެފާނު (އެބަހީ: މުޙައްމަދުގެފާނު) އެހެންފަހަރަކުވެސް އެ މަލާއިކަތާ ދެކެވަޑައިގަތްކަން ކަށަވަރެވެ.","",""],["","","","عند سدرة المنتهى","ސިދުރަތުލް މުންތަހާގެ ކައިރިންނެވެ.","",""],["","","","عندها جنة المأوى","އެތާނގެ ކައިރީގައި ޖައްނަތުލްމައުވާ ވެއެވެ. (އެއީ މުއުމިނު ތަކުންގެ ފުރާނަތަކުގެ މަރުކަޒެވެ.)","",""],["","","","إذ يغشى السدرة ما يغشى","ސިދުރަތުލް މުންތަހާ ފޮރުވައިލި (ފުރިހަމަ) ކަމެއްއައިސް ފޮރުވައިލި ހިނދުގައެވެ.","",""],["","","","ما زاغ البصر وما طغى","އެކަލޭގެފާނުގެ ލޯފުޅު އެކިފަރާތްފަރާތަކަށް ނުދެއެވެ. އަދި ދެކެވަޑައިގަތުމަށް ކަނޑައަޅުއްވާފައިވާތަން ފަހަނަޅައިވެސް ނުމެދޭމެއެވެ.","",""],["","","","لقد رأى من آيات ربه الكبرى","ހަމަކަށަވަރުން، އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ކުޅަދުންވަންތަކަމުގެ ބޮޑެތި ހެކިތައް، އެކަލޭގެފާނު ދެކެވަޑައިގަތްކަން ކަށަވަރެވެ.","",""],["","","","أفرأيتم اللات والعزى","ފަހެ، ލާތައާއި، ޢުއްޒާއާމެދު ތިޔަބައިމީހުން ވިސްނައި ބެލީމުހެއްޔެވެ؟","",""],["","","","ومناة الثالثة الأخرى","އަދި މަނާތެވެ ކިއުނު އަނެއް ތިންވަނަ ބުދާ މެދުވެސްމެއެވެ.","",""],["","","","ألكم الذكر وله الأنثى","ތިޔަބައިމީހުންނަށް ފިރިހެންދަރިންވެފައި، އެކަލާނގެއަށް އަންހެންދަރިން ވަނީ ހެއްޔެވެ؟","",""],["","","","تلك إذا قسمة ضيزى","(އެހެންވަނީނަމަ) އެއީ ހައްގު މަގުން އެއްކިބާވެގެންވާ ބައިކުރުމެކެވެ.","",""],["","","","إن هي إلا أسماء سميتموها أنتم وآباؤكم ما أنزل الله بها من سلطان إن يتبعون إلا الظن وما تهوى الأنفس ولقد جاءهم من ربهم الهدى","އެއީ ތިޔަބައިމީހުންނާއި، ތިޔަބައިމީހުންގެ ކާބަފައިން ކިޔައިގެންއުޅޭ ހުސް ނަންތަކެއް ކަމުގައިނޫނީ ނުވެތެވެ. އެތަކެއްޗަށް ﷲއެއްވެސްބާރެއް ދެއްވައިފައެއް ނުވެތެވެ. ހީއަކަށާއި، ހަވާނަފްސުގެ އެދުންތަކަކަށް މެނުވީ އެއުރެން ތަބާ ވާކަމުގައި ނުވެތެވެ. ހަމަކަށަވަރުން، އެއުރެންނާ ހަމަޔަށް އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ތެދުމަގު އައިސްފައިވާކަން ކަށަވަރެވެ.","",""],["","","","أم للإنسان ما تمنى","އަދި ކިއެއްތަ! އިންސާނާއަށް އޭނާ އެދޭހާކަމެއް ލިބޭހެއްޔެވެ؟","",""],["","","","فلله الآخرة والأولى","ފަހެ، ދުނިޔެއާއި، އާޚިރަތްގެ ކަންތައް މިލްކުވެ ހާއްސަ ވެގެންވަނީ ﷲއަށެވެ.","",""],["","","","وكم من ملك في السماوات لا تغني شفاعتهم شيئا إلا من بعد أن يأذن الله لمن يشاء ويرضى","އަދި ﷲ އިރާދަކުރައްވާ މީހަކަށް އެކަލާނގެ އިޒުނަ ދެއްވައި ރުހިވޮޑިގަތުމަށްފަހުގައި މެނުވީ، އެއުރެންގެ ޝަފާއަތުން އެއްވެސްކަމެއް ފުއްދައިނުދޭ ކިތައްކިތައް މަލާއިކަތުން އުޑުތަކުގައި ވޭހެއްޔެވެ؟","",""],["","","","إن الذين لا يؤمنون بالآخرة ليسمون الملائكة تسمية الأنثى","ހަމަކަށަވަރުން، އާޚިރަތަށް އީމާން ނުވާމީހުން މަލާއިކަތުންނަށް، އަންހެނުންގެ ނަމުން ނަންދޭކަން ކަށަވަރެވެ.","",""],["","","","وما لهم به من علم إن يتبعون إلا الظن وإن الظن لا يغني من الحق شيئا","އެއުރެންނަށް އެކަމުގެ އެއްވެސް އިލްމެއް ލިބިގެންނުވާ ޙާލު ގައެވެ. ހީއަކަށް މެނުވީ އެއުރެން ތަބާ ވާކަމުގައެއް ނުވެތެވެ. އަދި ހަމަކަށަވަރުން، ހީއަކީ ހައްގުގެ ބަދަލުގައި އެއްވެސްކަމެއް ފުއްދައިދޭނެ އެއްޗެއްނޫނެވެ.","",""],["","","","فأعرض عن من تولى عن ذكرنا ولم يرد إلا الحياة الدنيا","ފަހެ، ތިމަންރަސްކަލާނގެ ހަނދާންކުރުމުން އެއްކިބާވެ، ފުރަގަސްދީ، އަދި ދުނިޔޭގެ ދިރިއުޅުން ނޫންކަމެއް ނޭދޭމީހާ، ކަލޭގެފާނު ދޫކޮށްލައްވާށެވެ!","",""],["","","","ذلك مبلغهم من العلم إن ربك هو أعلم بمن ضل عن سبيله وهو أعلم بمن اهتدى","އިލްމުގެ ތެރެއިން އެއުރެންނަށް ލިބިފައިވާ މިންވަރަކީ އެއީއެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، އެކަލާނގެ މަގުން ފުރެދިގެންދިޔަމީހާ ދެނެވޮޑިގަތުން ބޮޑެވެ. އަދި އެކަލާނގެ، ތެދުމަގު ލިބިގަތްމީހާ ދެނެވޮޑިގަތުންވެސް ބޮޑުމެއެވެ.","",""],["","","","ولله ما في السماوات وما في الأرض ليجزي الذين أساءوا بما عملوا ويجزي الذين أحسنوا بالحسنى","އަދި އުޑުތަކާއި، ބިމުގައިވާހާ އެއްޗެއް މިލްކުވެގެންވަނީ ﷲއަށެވެ. އެއީ ނުބައި ޢަމަލުކުޅަމީހުންނަށް އެއުރެންކުޅަ ނުބައި ޢަމަލަށް ޖަޒާދެއްވުމަށެވެ. އަދި ހެޔޮ ޢަމަލުކުޅަމީހުންނަށް ހެޔޮ ޖަޒާ ދެއްވުމަށެވެ.","",""],["","","","الذين يجتنبون كبائر الإثم والفواحش إلا اللمم إن ربك واسع المغفرة هو أعلم بكم إذ أنشأكم من الأرض وإذ أنتم أجنة في بطون أمهاتكم فلا تزكوا أنفسكم هو أعلم بمن اتقى","އެއުރެންނީ، ކުދި ފާފަތައް ފިޔަވައި، ބޮޑު ފާފަތަކާއި، ފާޙީޝް ކަންތަކުން ދުރުވެގަންނަ މީހުންނެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، ފާފަފުއްސެވުން ތަނަވަސް ރަސްކަލާނގެއެވެ. ތިޔަބައިމީހުން ބިމުން ހެއްދެވި ހިނދުގައްޔާއި، ތިޔަބައިމީހުންގެ މައިންގެ ބަނޑުތަކުގައި ޅަދަރިންގެ ގޮތުގައި ތިޔަބައިމީހުން ތިބިހިނދުގައިވެސް، އެކަލާނގެ ތިޔަބައިމީހުންގެ ކަންތައް ދެނެވޮޑިގަތުން ބޮޑެވެ. ފަހެ، ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތަކަށް ތާރީފުކޮށް ފަޚުރުވެރިނުވާށެވެ! ތަގުވާވެރިވީމީހުންގެ ކަންތައް އެކަލާނގެ ދެނެވޮޑިގަތުން ބޮޑެވެ.","",""],["","","","أفرأيت الذي تولى","އީމާންކަމުން އެއްކިބާވެ (މުދަލުން) ކުޑަ އެތިކޮޅެއްދީ (އަނެއްބައި) ހިފެހެއްޓިމީހާ ފަހެ، ކަލޭގެފާނު ދެކެވަޑައިގަތީމުތޯއެވެ؟","",""],["","","","وأعطى قليلا وأكدى","އީމާންކަމުން އެއްކިބާވެ (މުދަލުން) ކުޑަ އެތިކޮޅެއްދީ (އަނެއްބައި) ހިފެހެއްޓިމީހާ ފަހެ، ކަލޭގެފާނު ދެކެވަޑައިގަތީމުތޯއެވެ؟","",""],["","","","أعنده علم الغيب فهو يرى","ފަހެ، އޭނާޔަށް (އެކަން) އެނގުމަށް އޭނާޔަށް ޣައިބުގެ އިލްމު ލިބިފައިވަނީ ހެއްޔެވެ؟","",""],["","","","أم لم ينبأ بما في صحف موسى","އަދި ކީއްހެއްޔެވެ؟ މޫސާގެފާނުގެ ފަތްފުށްތަކުގައިވާ ތަކެތީގެ ޚަބަރު އޭނާޔަށް ނުލިބެނީހެއްޔެވެ؟","",""],["","","","وإبراهيم الذي وفى","އަދި (ހުރިހާ ކަންތައްތަކެއް) ފުރިހަމަގޮތުގައި ފުއްދެވި، އިބްރާހީމްގެފާނު (ގެ ފަތްފުށްތައް) ވެސްމެއެވެ.","",""],["","","","ألا تزر وازرة وزر أخرى","އަދި ފާފަވެރި އެއްވެސް ނަފްސެއް، އެހެން ނަފްސެއްގެ ފާފަޔެއް ނުއުފުލާނެތެވެ.","",""],["","","","وأن ليس للإنسان إلا ما سعى","އަދި އިންސާނާޔަށް އޭނާ ކުޅަ ޢަމަލެއް (ގެ ޖަޒާ) މެނުވީ ނުވެއެވެ.","",""],["","","","وأن سعيه سوف يرى","އަދި ހަމަކަށަވަރުން، އޭނާ ކުޅަ ޢަމަލެއް ނިކަންހުރެ އޭނާ ދެކޭނެތެވެ.","",""],["","","","ثم يجزاه الجزاء الأوفى","ދެން އޭނާ ކުޅަ ޢަމަލަށް އެންމެފުރިހަމަ ޖަޒާ ދެއްވާނެއެވެ.","",""],["","","","وأن إلى ربك المنتهى","އަދި އެނބުރި ދިއުންވަނީ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","وأنه هو أضحك وأبكى","އަދި ހެއްވަވަނީވެސް، އަދި ރޮއްވަވަނީވެސް ހަމައެކަލާނގެއެވެ.","",""],["","","","وأنه هو أمات وأحيا","އަދި މަރުގަންނަވަނީވެސް، އަދި ދިރުއްވަނީވެސް ހަމައެކަލާނގެއެވެ.","",""],["","","","وأنه خلق الزوجين الذكر والأنثى","އަދި ރަޙިމުގެ ތެރެޔަށް މަނިފޮދެއް އެޅޭހިނދު އެއިން، ފިރިހެން އަންހެން ދެބާވަތް ހެއްދެވީވެސް އެކަލާނގެއެވެ.","",""],["","","","من نطفة إذا تمنى","އަދި ރަޙިމުގެ ތެރެޔަށް މަނިފޮދެއް އެޅޭހިނދު އެއިން، ފިރިހެން އަންހެން ދެބާވަތް ހެއްދެވީވެސް އެކަލާނގެއެވެ.","",""],["","","","وأن عليه النشأة الأخرى","އަދި (މަރުވުމަށްފަހު) އަލުން ދިރުއްވުންވަނީވެސް އެކަލާނގެއަށެވެ.","",""],["","","","وأنه هو أغنى وأقنى","އަދި މުއްސަނދިކުރައްވަނީވެސް، އަދި ފަގީރުކުރައްވަނީވެސް އެކަލާނގެއެވެ.","",""],["","","","وأنه هو رب الشعرى","އެކަލާނގެއީ، އައްޝިޢުރާ އޭ ކިއުނު ތަރީގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["","","","وأنه أهلك عادا الأولى","އަދި ކުރީގެ ޢާދު ބާގައިމީހުން ހަލާކުކުރައްވައި ނެތިކުރެއްވީވެސް އެކަލާނގެއެވެ.","",""],["","","","وثمود فما أبقى","އަދި ޘަމޫދު ބާގައިމީހުންގެ އެކަކުވެސް ނުބަހައްޓަވައި ހަލާކުކުރެއްވިއެވެ.","",""],["","","","وقوم نوح من قبل إنهم كانوا هم أظلم وأطغى","އަދި އޭގެކުރިން ނޫޙުގެފާނުގެ ގައުމުގެމީހުން ހަލާކުކުރެއްވިއެވެ. ހަމަކަށަވަރުން، އެއުރެންވީ އަނިޔާވެރިކަންބޮޑު، އަދި އުރެދުންބޮޑު ބަޔަކު ކަމުގައެވެ.","",""],["","","","والمؤتفكة أهوى","އަދި ލޫޠު ބާގައިމީހުންގެ ރަށް ބަންޑުންޖައްސަވައި ވައްޓަވައިލެއްވިއެވެ.","",""],["","","","فغشاها ما غشى","ފަހެ، އެރަށަށް ޖެއްސެވި އަޒާބެއް ޖެއްސެވިއެވެ.","",""],["","","","فبأي آلاء ربك تتمارى","ފަހެ، ތިބާ ޝައްކުކުރަނީ ތިބާގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","هذا نذير من النذر الأولى","މިއީ (އެބަހީ: މުޙައްމަދުގެފާނީ) އިސްވެދިޔަ ނަޛީރު ންފަދަ ނަޛީރެކެވެ.","",""],["","","","أزفت الآزفة","ގިޔާމަތް ދުވަސް ގާތްވެއްޖެއެވެ.","",""],["","","","ليس لها من دون الله كاشفة","ﷲ މެނުވީ އެދުވަސް ހާމަކުރާނޭ އެއްވެސްފަރާތެއް ނުވެއެވެ.","",""],["","","","أفمن هذا الحديث تعجبون","ފަހެ، ތިޔަބައިމީހުން އަޖާއިބު ވަނީ އަދި ނުރޮއި ހެނީ މިވާހަކަތަކާމެދުގައި (އެބަހީ: ގުރްއާން އާމެދުގައި) ހެއްޔެވެ؟","",""],["","","","وتضحكون ولا تبكون","ފަހެ، ތިޔަބައިމީހުން އަޖާއިބު ވަނީ އަދި ނުރޮއި ހެނީ މިވާހަކަތަކާމެދުގައި (އެބަހީ: ގުރްއާން އާމެދުގައި) ހެއްޔެވެ؟","",""],["","","","وأنتم سامدون","އަދި ތިޔަބައިމީހުންވަނީ، ބޮޑާވެ ޣާފިލު ވެގެންނެވެ.","",""],["","","","فاسجدوا لله واعبدوا","ފަހެ، ތިޔަބައިމީހުން ﷲއަށް ސަޖިދަކުރާށެވެ! (އަދި ހަމައެކަނި) އެކަލާނގެއަށް އަޅުކަންކުރާށެވެ!","",""],["","","","بسم الله الرحمن الرحيم اقتربت الساعة وانشق القمر","ގިޔާމަތް ވުމުގެ ވަގުތު ގާތްވެއްޖެއެވެ. އަދި ހަނދު އިރިއްޖެއެވެ.","",""],["","","","وإن يروا آية يعرضوا ويقولوا سحر مستمر","އަދި އެއުރެންނަށް ހެތްކެއް ފެންނަނީނަމަ، އެއުރެން ފުރަގަސްދެތެވެ. އަދި ބުނެތެވެ. މިއީ ދެމިހުންނަނިވި ޖާދޫއެކެވެ.","",""],["","","","وكذبوا واتبعوا أهواءهم وكل أمر مستقر","އަދި އެއުރެން (ހައްގު ބަސްފުޅު) ދޮގުކުޅައޫއެވެ. އަދި އެއުރެންގެ އަމިއްލަ އެދުންތަކަށް އެއުރެން ތަބާ ވިއެވެ. ކޮންމެކަމަކީ ނިމުމަކަށްގޮސް ހަމަޖެހޭނެކަމެކެވެ.","",""],["","","","ولقد جاءهم من الأنباء ما فيه مزدجر","ހަމަކަށަވަރުން، ޚަބަރުތަކުގެ ތެރެއިން އެކަންކަމުގައި އިބްރަތް ހިމެނިގެންވާ ޚަބަރުތައް އެއުރެންގެ ގާތަށްއައެވެ.","",""],["","","","حكمة بالغة فما تغن النذر","(މިއީ) ފުރިހަމަވެގެންވާ ހިކުމަތެކެވެ. ފަހެ، އިންޒާރުތައް (އެއުރެންނަކަށް އެއްވެސްކަމެއް) ފުއްދައެއް ނުދެތެވެ.","",""],["","","","فتول عنهم يوم يدع الداع إلى شيء نكر","ފަހެ، ނުރުހެވޭކަމަކަށް ގޮވާމީހާ ގޮވާދުވަހު، ކަލޭގެފާނު އެއުރެންނާ އެއްކިބާވެވަޑައިގަންނަވާށެވެ!","",""],["","","","خشعا أبصارهم يخرجون من الأجداث كأنهم جراد منتشر","އެއުރެންގެ ލޯތައް ތިރިވެ، ނިކަމެތިވެގެންވާ ޙާލު، ފެތުރިގަންނަ ގޮއްފުޅަނގިތަކެއް ފަދައިން ކަށްވަޅުތަކުން އެއުރެން ނުކުންނާނެތެވެ.","",""],["","","","مهطعين إلى الداع يقول الكافرون هذا يوم عسر","ގޮވާފަރާތަށް (ދިޔުމަށް) އަވަސްވެގަންނަ ޙާލު ގައެވެ. ކާފިރު ވިމީހުން ބުނާނެތެވެ. މިއީ ދަތި އުނދަގޫ ދުވަހެކެވެ.","",""],["","","","كذبت قبلهم قوم نوح فكذبوا عبدنا وقالوا مجنون وازدجر","އެއުރެންގެ ކުރިން ނޫޙުގެފާނުގެ ގައުމުގެމީހުންވެސް ދޮގުކުރޫއެވެ. ފަހެ، އެއުރެން ތިމަންރަސްކަލާނގެ އަޅާ ދޮގުކުރޫއެވެ. އަދި އެއުރެން ބުނޫއެވެ. މޮޔައެކެވެ. އަދި އެއުރެން އެކަލޭގެފާނަށް ބިރުދައްކައި ހެދިއެވެ.","",""],["","","","فدعا ربه أني مغلوب فانتصر","ފަހެ، އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް، އެކަލާގެފާނު ދުއާކުރައްވައި ވިދާޅުވިއެވެ. ހަމަކަށަވަރުން، މިއަޅާވަނީ، ދެރަކޮށްލައިފައެވެ. ފަހެ، (މިއަޅާޔަށް) ނަސްރު ދެއްވާނދޭވެ!","",""],["","","","ففتحنا أبواب السماء بماء منهمر","ފަހެ، ބޯކޮށް އޮހިގަންނަ ފެނަކަށް ތިމަންރަސްކަލާނގެ އުޑުގެ ދޮރުތައް ހުޅުއްވެވީމެވެ.","",""],["","","","وفجرنا الأرض عيونا فالتقى الماء على أمر قد قدر","އަދި ތިމަންރަސްކަލާނގެ ފެންއާރުތަކަކަށް ބިންގަނޑު ފެޅުއްވީމެވެ. ފަހެ، ނިޔާކުރައްވާފައިވާ ކަމެއްގެ މައްޗަށް އެ ފެން (އެބަހީ: އުޑުން އޮހުނު ފެނާއި، ބިމުންއެރި ފެން) ބައްދަލުވިއެވެ.","",""],["","","","وحملناه على ذات ألواح ودسر","އަދި ފިލާތަކަކާއި، މޮހޮރުތަކަކުން ހަދާފައިވާ ނަވެއްގައި، ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނު އުފުއްލެވީމެވެ.","",""],["","","","تجري بأعيننا جزاء لمن كان كفر","ތިމަންރަސްކަލާނގެ ބައްލަވާވޮޑިގަތުމާއެކު، އެ ނައު، ދުވަމުންދެތެވެ. (އެއުރެން) ދޮގުކުރި ކަލޭގެފާނަށް (އެބަހީ: ނޫޙުގެފާނަށް) ހެޔޮ ޖަޒާއެއްކަމުގައެވެ.","",""],["","","","ولقد تركناها آية فهل من مدكر","އަދި ހަމަކަށަވަރުން، އެކަންތައްއެއީ، ހެތްކެއްކަމުގައި ތިމަންރަސްކަލާނގެ ލެހެއްޓެވީމެވެ. ފަހެ، ހަނދުމަކުރާ މީހަކުވޭހެއްޔެވެ؟","",""],["","","","فكيف كان عذابي ونذر","ފަހެ، ތިމަންރަސްކަލާނގެ އަޒާބާއި، ތިމަންރަސްކަލާނގެ އިންޒާރުތައްވީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","ولقد يسرنا القرآن للذكر فهل من مدكر","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ގުރްއާން ހަނދުމަކުޅައުމަށް ފަސޭހަކޮށް ދެއްވީމެވެ. ފަހެ، ހަނދުމަކުރާ މީހަކު ވޭހެއްޔެވެ؟","",""],["","","","كذبت عاد فكيف كان عذابي ونذر","ޢާދު ބާގައިމީހުންވެސް ދޮގުކުރޫއެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ އަޒާބާއި ތިމަންރަސްކަލާނގެ އިންޒާރުތައްވީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","إنا أرسلنا عليهم ريحا صرصرا في يوم نحس مستمر","ދެމިހުންނަނިވި ސުންޕާކަމުގެ ދުވަހެއްގައި ގަދަ އަޑާއި، ގަދަ ފިނީގެ ވަޔެއް ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް ފޮނުއްވީމެވެ.","",""],["","","","تنزع الناس كأنهم أعجاز نخل منقعر","އެ ވައިރޯޅިއައިސް، މީސްތަކުން (ތިބިތަނުން) ލުހެލަތެވެ. ވެއްޓިފައިވާ ކަދުރު ރުކުގެ ބުޑުތަކެއްފަދައިން އެއުރެން ވާކަހަލައެވެ.","",""],["","","","فكيف كان عذابي ونذر","ފަހެ، ތިމަންރަސްކަލާނގެ އަޒާބާއި ތިމަންރަސްކަލާނގެ އިންޒާރުތައްވީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","ولقد يسرنا القرآن للذكر فهل من مدكر","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ގުރްއާން ހަނދުމަކުޅައުމަށް ފަސޭހަކޮށް ދެއްވީމެވެ. ފަހެ، ހަނދުމަކުރާމީހަކު ވޭހެއްޔެވެ؟","",""],["","","","كذبت ثمود بالنذر","ޘަމޫދު ބާގައިމީހުން އިންޒާރުތައް ދޮގުކުރޫއެވެ.","",""],["","","","فقالوا أبشرا منا واحدا نتبعه إنا إذا لفي ضلال وسعر","ފަހެ އެއުރެން ބުނޫއެވެ. ތިމަންމެން ތަބާ ވާންވީ ތިމަންމެންގެ ތެރެއިން އެންމެ އާދަމުގެދަރިޔަކަށް ހެއްޔެވެ؟ އެހެންވިއްޔާ، ހަމަކަށަވަރުން، ތިމަންމެންވާހުށީ، މަގުފުރެދުމާއި، މޮޔަކަމެއްގެ ތެރޭގައިކަން ކަށަވަރެވެ.","",""],["","","","أألقي الذكر عليه من بيننا بل هو كذاب أشر","ތިމަންމެންގެ ތެރެއިން، ހަމަ އޭނާޔަށް ވަހީ ބާވައިލެއްވީހެއްޔެވެ؟ އަދި ކިއެއްތަ! އޭނާޔަކީ ބޮޑު ދޮގުވެރި، ބޮޑާ މީހެކެވެ.","",""],["","","","سيعلمون غدا من الكذاب الأشر","ބޮޑު ދޮގުވެރި، ބޮޑާ މީހަކީ ކާކުކަން މާދަމާ (އެބަހީ: އަޒާބު އަންނަދުވަހު) އެއުރެންނަށް ނިކަންހުރެ އެނގޭނެތެވެ.","",""],["","","","إنا مرسلو الناقة فتنة لهم فارتقبهم واصطبر","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެންނަށް އިމްތިހާނެއްގެ ގޮތުގައި އަންހެން ޖަމަލެއް (ނެރުއްވައި) ފޮނުއްވާހުށީމެވެ. ފަހެ، ކަލޭގެފާނު އެއުރެން ކަންކުރާގޮތް ބައްލަވައި އިންތިޒާރުކުރައްވާށެވެ! އަދި ކެތްތެރިވެވަޑައިގަންނަވާށެވެ!","",""],["","","","ونبئهم أن الماء قسمة بينهم كل شرب محتضر","އަދި ކަލޭގެފާނު އެއުރެންނަށް އަންގަވާށެވެ! ހަމަކަށަވަރުން، ފެން ވަނީ އެއުރެންގެ މެދުގައި (އެބަހީ: އެއުރެންނާއި އެ ޖަމަލާ ދެމެދު) ބައްސަވައިފައެވެ. ކޮންމެ ބަޔަކަށްމެ، އެބަޔެއްގެ ބުއިން (އެބަޔެއްގެ ދުވަހު) ޙާޒިރުުކުރައްވާފައިވެއެވެ.","",""],["","","","فنادوا صاحبهم فتعاطى فعقر","ފަހެ، އެއުރެންގެ އެކުވެރިޔާއަށް އެއުރެން ގޮވޫއެވެ. ފަހެ، އޭނާ ކަނޑި ލިބިގަނެ، ޖަމަލު މަރައިލިއެވެ.","",""],["","","","فكيف كان عذابي ونذر","ފަހެ، ތިމަންރަސްކަލާނގެ އަޒާބާއި، ތިމަންރަސްކަލާނގެ އިންޒާރުތައްވީ ކޮންފަދައަކުންހެއްޔެވެ؟","",""],["","","","إنا أرسلنا عليهم صيحة واحدة فكانوا كهشيم المحتظر","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް ބިރުވެރި އެންމެ އަޑެއް ފޮނުއްވީމެވެ. ފަހެ، ގެރިބަކަރި ހުއިހައްޕާމީހާ ގެންގުޅޭ ހިކި ހުއިތަކެއް ފަދައިން އެއުރެންވޫއެވެ.","",""],["","","","ولقد يسرنا القرآن للذكر فهل من مدكر","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ގުރްއާން ހަނދުމަކުޅައުމަށް ފަސޭހަކޮށް ދެއްވީމެވެ. ފަހެ، ހަނދުމަކުރާ މީހަކު ވޭހެއްޔެވެ؟","",""],["","","","كذبت قوم لوط بالنذر","ލޫޠުގެފާނުގެ ގައުމުގެމީހުން އިންޒާރުތައް ދޮގުކުރޫއެވެ.","",""],["","","","إنا أرسلنا عليهم حاصبا إلا آل لوط نجيناهم بسحر","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެންގެމައްޗަށް ހިލައިގެ ވާރޭ ފޮނުއްވީމެވެ. ލޫޠުގެފާނުގެ އަހުލުވެރިން މެނުވީއެވެ. ދަންވަރުގެ ވަގުތެއްގައި ތިމަންރަސްކަލާނގެ އެއުރެން ސަލާމަތްކުރެއްވީމެވެ.","",""],["","","","نعمة من عندنا كذلك نجزي من شكر","ތިމަންރަސްކަލާނގެ ހަޒުރަތުން ދެއްވި ނިއުމަތެއްގެގޮތުގައެވެ. ޝުކުރުކުރާ މީހަކަށް އެފަދައިން ތިމަންރަސްކަލާނގެ ޖަޒާދެއްވަމެވެ.","",""],["","","","ولقد أنذرهم بطشتنا فتماروا بالنذر","އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އުގޫބާތްގެ ވާހަކައިން، އެކަލޭގެފާނު އެއުރެންނަށް އިންޒާރުކުރެއްވިއެވެ. ފަހެ، އެއުރެން އެ އިންޒާރު ތަކާމެދު ޝައްކުކުރޫއެވެ.","",""],["","","","ولقد راودوه عن ضيفه فطمسنا أعينهم فذوقوا عذابي ونذر","އަދި ހަމަކަށަވަރުން، އެކަލޭގެފާނުގެ މެހުމާނުންނާމެދު، ނުބައިކަންތައް ކުރުމަށްޓަކައި އެކަލޭގެފާނުގެ އަރިހުން އެއުރެން އެދިގަތެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ އެއުރެންގެ ލޯތައް ކަނުކުރެއްވީމެވެ. (އަދި އެންގެވީމެވެ.) ފަހެ، ތިޔަބައިމީހުން ތިމަންރަސްކަލާނގެ އަޒާބާއި، އިންޒާރުގެ ރަހަ ލިބިގަންނާށެވެ!","",""],["","","","ولقد صبحهم بكرة عذاب مستقر","އަދި ހަމަކަށަވަރުން، ފަތިހެއްގެ ފަތިސްވަގުތުގައި ދެމިހުންނަނިވި އަޒާބު އައިސް އެއުރެންނަށް ޖެހުނެވެ.","",""],["","","","فذوقوا عذابي ونذر","ފަހެ، ތިޔަބައިމީހުން ތިމަންރަސްކަލާނގެ އަޒާބާއި، އިންޒާރުގެ ރަހަ ލިބިގަންނާށެވެ!","",""],["","","","ولقد يسرنا القرآن للذكر فهل من مدكر","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ގުރްއާން ހަނދުމަކުޅައުމަށް ފަސޭހަކޮށް ދެއްވީމެވެ. ފަހެ، ހަނދުމަކުރާ މީހަކު ވޭހެއްޔެވެ؟","",""],["","","","ولقد جاء آل فرعون النذر","ހަމަކަށަވަރުން، ފިރްޢައުނުގެމީހުންގެ ގާތަށް އިންޒާރުތައް އައެވެ.","",""],["","","","كذبوا بآياتنا كلها فأخذناهم أخذ عزيز مقتدر","ތިމަންރަސްކަލާނގެ ދެއްކެވި ހުރިހާ މުއުޖުޒާތްތައް އެއުރެން ދޮގުކުރޫއެވެ. ފަހެ، ޢަޒީޒުވަންތަ، ކުޅަދުންވަންތަ ކަލެއްގެ ހިއްޕެވުމަކުން، ތިމަންރަސްކަލާނގެ އެއުރެން ހިއްޕެވީމެވެ.","",""],["","","","أكفاركم خير من أولئكم أم لكم براءة في الزبر","އެއުރެންނަށްވުރެ ތިޔަބައިމީހުންގެ ކާފިރުން، ހެޔޮކަން ބޮޑީހެއްޔެވެ؟ ނުވަތަ ބާވައިލެއްވި ފޮތްތަކުގައި އަޒާބުން މިންޖުވުމެއް، ތިޔަބައިމީހުންނަށްޓަކައި ވަނީހެއްޔެވެ؟","",""],["","","","أم يقولون نحن جميع منتصر","ނުވަތަ ތިމަންމެން އެންމެންނީ، ނަސްރު ލިބިގެންވާ ބަޔެކޭ އެއުރެން ބުނަނީހެއްޔެވެ؟","",""],["","","","سيهزم الجمع ويولون الدبر","އެ (ކާފިރުންގެ) ޖަމާއަތް ދެރަކުރައްވައި، ބަލިކޮށްލައްވާނެތެވެ. އަދި އެއުރެން ފުރަގަސްދީ، ފިލަން ދުވާނެތެވެ.","",""],["","","","بل الساعة موعدهم والساعة أدهى وأمر","އަދި ކިއެއްތަ! އެއުރެންނަށް (އަޒާބު ދެއްވުމަށް) ކަނޑައަޅުއްވާފައިވާ ވަގުތަކީ، ގިޔާމަތް ވުމުގެ ވަގުތެވެ. އަދި ގިޔާމަތް ވުމުގެ ވަގުތު (އެއުރެންގެ މައްޗަށް) ދަތިކަން މާބޮޑެވެ. އަދި ހިތިކަންވެސް މާބޮޑުމެއެވެ.","",""],["","","","إن المجرمين في ضلال وسعر","ހަމަކަށަވަރުން، ކުށްވެރިންވަނީ، މަގުފުރެދުމެއްގައެވެ. އަދި އަނދައަނދާ ހުންނަ ނަރަކައިގެ އަލިފާނުގައެވެ.","",""],["","","","يوم يسحبون في النار على وجوههم ذوقوا مس سقر","(އެއީ) އެއުރެންގެ މޫނުތައް ވަތަށްލައި، ނަރަކައިގެ ތެރޭގައި ދަމައި، ގެންދަވާދުވަހެވެ. (އަދި އެއުރެންނަށް އަންގަވާނެތެވެ.) ނަރަކައިގެ އަލިފާންގަނޑު ބީހުމުގެ ރަހަ ތިޔަބައިމީހުން ލިބިގަންނާށެވެ!","",""],["","","","إنا كل شيء خلقناه بقدر","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކޮންމެއެއްޗެއް ހައްދަވާފައިވަނީ، ކަނޑައަޅުއްވާފައިވާ ވަކިމިންވަރަކަށެވެ.","",""],["","","","وما أمرنا إلا واحدة كلمح بالبصر","އަދި ތިމަންރަސްކަލާނގެ އަމުރުފުޅު އެއީ، އެއް އަމުރުފުޅެއް ކަމުގައިމެނުވީ ނުވެއެވެ. ލޮލުގެ އެސްފިޔަޖަހައިލުން ފަދައިންނެވެ.","",""],["","","","ولقد أهلكنا أشياعكم فهل من مدكر","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، ތިޔަބައިމީހުންނާ އެއްފަދަވެގެންވާ މީހުން ހަލާކުކުރެއްވީމެވެ. ފަހެ، ހަނދުމަކުރާ މީހަކު ނުވޭހެއްޔެވެ؟","",""],["","","","وكل شيء فعلوه في الزبر","އަދި އެއުރެންކުޅަ ކޮންމެކަމެއް، ފަތްފުށްތަކުގައިވެއެވެ.","",""],["","","","وكل صغير وكبير مستطر","އަދި ކުދިބޮޑު އެންމެހާ ކަންތައް (އައްލައުޙުލް މަޙްފޫޡުގައި) ލިޔުއްވާފައިވެއެވެ.","",""],["","","","إن المتقين في جنات ونهر","ހަމަކަށަވަރުން، ތަގުވާވެރިންވަނީ، ސުވަރުގެތަކާއި، ބާވަތްބާވަތުގެ ކޯރުތަކުގެ ނިއުމަތް ގައެވެ.","",""],["","","","في مقعد صدق عند مليك مقتدر","ހިތްހަމަޖެހޭ، އުފާވެރިކަމުގެ ދާނެއްގައެވެ. ކުޅަދުންވަންތަ، ރަސްވަންތަ ރަސްކަލާނގެ ހަޒުރަތު ގައެވެ.","",""],["","","","بسم الله الرحمن الرحيم الرحمن","ރަޙްމާންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","علم القرآن","އެކަލާނގެ ގުރްއާން އުނގަންނައިދެއްވިއެވެ.","",""],["","","","خلق الإنسان","އެކަލާނގެ އިންސާނާ ހެއްދެވިއެވެ.","",""],["","","","علمه البيان","އެކަލާނގެ އެ އިންސާނާއަށް ބަސްމޮށުންތެރިކަން އުނގަންނައިދެއްވިއެވެ.","",""],["","","","الشمس والقمر بحسبان","އިރާއި، ހަނދު، ބަރާބަރު ހިސާބެއްގެ މަތިންހިނގައެވެ.","",""],["","","","والنجم والشجر يسجدان","އަދި ފަތްޕިލާވެއްޔާއި، ގަސްގަހާގެހި، އެކަލާނގެއަށް ކިޔަމަންވެ، ސަޖިދަކުރެތެވެ.","",""],["","","","والسماء رفعها ووضع الميزان","އަދި އެކަލާނގެ އުޑު އުފުއްލެވިއެވެ. އަދި ޢަދުލު އިންޞާފު ލެއްވިއެވެ.","",""],["","","","ألا تطغوا في الميزان","މިނެކިރުމުގައި ތިޔަބައިމީހުން އަނިޔާވެރި ނުވުމަށްޓަކައެވެ.","",""],["","","","وأقيموا الوزن بالقسط ولا تخسروا الميزان","ޢަދުލު އިންޞާފުގެ މަތިން ތިޔަބައިމީހުން މިނެކިރުން ހަމަކުރާށެވެ! އަދި މިނެކިރުމުގައި ތިޔަބައިމީހުން ގެއްލުން ނުކުރާށެވެ!","",""],["","","","والأرض وضعها للأنام","އަދި ޚަލްގު ތަކުންނަށްޓަކައި އެކަލާނގެ ބިން ލައްވާފައިވެއެވެ.","",""],["","","","فيها فاكهة والنخل ذات الأكمام","އެ ބިމުގައި މޭވާއާއި، އެތްތަކުގެވެރި ކަދުރު ރުއްތައް ވެއެވެ.","",""],["","","","والحب ذو العصف والريحان","އަދި ތޮށި ހުންނަ ގޮވާންތަކާއި، މީރުވަސްދުވާ މާމެލާމެލި ވެއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","އޭ (ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަ ދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަ ދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","خلق الإنسان من صلصال كالفخار","މުށިތަކެއްފަދަ ހިކި މަށިން، އެކަލާނގެ އިންސާނާ (އެބަހީ: އާދަމުގެފާނު) ހެއްދެވިއެވެ.","",""],["","","","وخلق الجان من مارج من نار","އަދި ދުންނާރާ އަލިފާނެއްގެ ހުޅުގަނޑުން، އެކަލާނގެ ޖިންނީން ހެއްދެވިއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަ ދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަ ދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","رب المشرقين ورب المغربين","އިރުއަރާ ދެތަނާއި، އިރުއޮއްސޭ ދެތަނުގެ ވެރިރަސްކަލާނގެއެވެ. (އެބަހީ: ދެ މޫސުމަށް އިރުއަރާ ދެތަނާއި، އޮއްސޭ ދެތަނުގެ ވެރިރަސްކަލާނގެއެވެ.)","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަ ދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަ ދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","مرج البحرين يلتقيان","އެކަލާނގެ ދެކަނޑު (އެބަހީ: ކޯރާއި، ކަނޑު) ހައްދަވައި، ފޮނުއްވިއެވެ. އެ ދެކަނޑު ހިނގަމުންގޮސް ބައްދަލުވެތެވެ.","",""],["","","","بينهما برزخ لا يبغيان","އެ ދެކަނޑު ދެމެދުގައި، ހުރަހެއްވެއެވެ. އެ ދެކަނޑުވެސް އެއްކަނޑު އަނެއް ކަނޑެއްގެ މައްޗަކަށް އަރައެއް ނުގަނެތެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަ ދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަ ދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","يخرج منهما اللؤلؤ والمرجان","އެ ދެކަނޑުން ރަންމުތާއި، މަރުޖާން ފައިދާވެ ނުކުމެއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަ ދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަ ދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","وله الجوار المنشآت في البحر كالأعلام","އަދި ކަނޑުގައި ދުއްވުމަށް ހަދާފައިވާ އުސްފަރުބަދަތައްފަދަ އުޅަނދުފަހަރު މަލަކަ ވެގެންވަނީ، އެކަލާނގެއަށެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަ ދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަ ދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","كل من عليها فان","އެ ބިންމަތީގައިވާ ކޮންމެ އެއްޗަކީ، ފަނާވެދަނިވި އެއްޗެކެވެ.","",""],["","","","ويبقى وجه ربك ذو الجلال والإكرام","އަދި ކަލޭގެފާނުގެ ވެރި، ކީރިތިވަންތަކަމާއި، މާތްވަންތަކަމުގެ ވެރިރަސްކަލާނގެ ޛާތުފުޅު ދެމިވޮޑިގެންވެއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަ ދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަ ދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","يسأله من في السماوات والأرض كل يوم هو في شأن","އުޑުތަކާއި، ބިމުގައިވާހާ ބަޔަކު އެކަލާނގެއަށް އެދި ދަންނަވަތެވެ. ކޮންމެ ހިނދުކޮޅެއްގައިމެ، އެކަލާނގެ ވޮޑިގެންވަނީ ކަމެއްގައެވެ. (އެބަހީ: ބަޔެއް އަޅުތަކުން ޢިއްޒަތް ތެރިކުރައްވައި، އަނެއްބައި އަޅުތަކުން ނިކަމެތި ކުރައްވައި، އެއްބަޔަކަށް ރިޒްގު ދެއްވައި، އަނެއްބަޔަކު މަޙްރޫމުކުރައްވަތެވެ.)","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަ ދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","سنفرغ لكم أيه الثقلان","އޭ ޖިންނީންނާއި، އިންސީންނާ ދެބާވަތުގެ މީހުންނޭވެ! ތިޔަ ދެބައިމީހުންގެ މެދުގައި ނިކަންހުރެ، ތިމަންރަސްކަލާނގެ ހުކުމްކުރައްވާ ހުށީމެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","يا معشر الجن والإنس إن استطعتم أن تنفذوا من أقطار السماوات والأرض فانفذوا لا تنفذون إلا بسلطان","އޭ ޖިންނީންނާއި، އިންސީންގެ ޖަމާއަތްގެ މީހުންނޭވެ! އުޑުތަކާއި، ބިމުގެ އެންމެހާ ފަރާތްތަކުން ނުކުމެގެން ދިޔުމަށް، ތިޔަބައިމީހުންނަށް ކުޅަދާނަވެގެންވާނަމަ، ފަހެ، ތިޔަބައިމީހުން ނުކުމެގެން ގޮސްބަލާށެވެ! ވަރުގަދަ ބާރަކުން މެނުވީ، ތިޔަބައިމީހުންނަކަށް ނުނުކުމެވޭނެތެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","يرسل عليكما شواظ من نار ونحاس فلا تنتصران","ތިޔަ ދެބައިމީހުންގެ މައްޗަށް (ގިޔާމަތް ދުވަހުން) އަލިފާނުގެ ހުޅުތަކާއި، ވިރިފައިވާ ލޮއި ފޮނުއްވާނެތެވެ. ފަހެ، ތިޔަބައިމީހުންނަށް ނަސްރެއް ނުލިބޭނެތެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","فإذا انشقت السماء فكانت وردة كالدهان","ފަހެ، އުޑު ފަޅަފަޅައިގެންދާހިނދު، ރަތްފިނިފެންމަލުގެ ކުލައިގައިވާ ތެޔޮގަނޑެއް ފަދައިން ވެދެއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","فيومئذ لا يسأل عن ذنبه إنس ولا جان","ފަހެ، އެދުވަހުން އެމީހެއްގެ ފާފަޔާމެދު އިންސިއަކާ، އަދި ޖިންނިއަކާވެސް ސުވާލެއް ނުކުރައްވާނެތެވެ. (އެހެނީ، އެދުވަހުން އެއުރެން ފާހަގަވެ، އެނގޭނެތެވެ.)","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","يعرف المجرمون بسيماهم فيؤخذ بالنواصي والأقدام","(އެދުވަހުން) ކުށްވެރިން އެއުރެންގެ ފާހަގައިން އެނގޭނެއެވެ. ފަހެ، ނިތްގަނޑުތަކާއި ފައިތަކުގައި ހިއްޕަވައިގެން، އެއުރެން ގެންދަވާނެތެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","هذه جهنم التي يكذب بها المجرمون","މިއީ ކުށްވެރިން ދޮގުކޮށް އުޅުނު ނަރަކަޔެވެ.","",""],["","","","يطوفون بينها وبين حميم آن","އެ ނަރަކައިގެ އަލިފާނާއި، އަދި ކެކިކެކިހުންނަ ހޫނުފެނާ ދެމެދުގައި، އެއުރެން ހިނގަހިނގާ ތިބޭނެތެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","ولمن خاف مقام ربه جنتان","އެމީހާގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ހުންނަންޖެހޭ ހުރުމާމެދު، ބިރުވެތިވެއްޖެ މީހާއަށް ދެ ސުވަރުގެ ހުށްޓެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","ذواتا أفنان","ހިޔާ ފެތުރިގެންވާ ގޮފިތަކުގެ ވެރި ދެ ސުވަރުގެއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","فيهما عينان تجريان","ހިނގަހިނގާ ހުންނަ ފެންއާރުގެ ދެ އާރު، އެ ދެ ސުވަރުގޭގައިވެއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަ ދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","فيهما من كل فاكهة زوجان","ކޮންމެ މޭވާއަކުން ދެބާވަތް އެ ދެ ސުވަރުގޭގައިވެއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","متكئين على فرش بطائنها من إستبرق وجنى الجنتين دان","(އެއުރެން ތިބޭހުށީ) ދާންތަކެއްގެ މަތީގައި ލެނގިގެންނެވެ. އެ ދާންތަކުގެ ބަތާނަ ވަނީވެސް އިސްތަބްރަގުންނެވެ. (އެބަހީ: ފަލަ ފަށުއިންނެވެ.) އަދި އެ ދެ ސުވަރުގޭގެ މޭވާތައް (ބިންނަ މީހުންނަށް) ކައިރިވެގެންވެއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","فيهن قاصرات الطرف لم يطمثهن إنس قبلهم ولا جان","ކަޅިތައް ޢިއްފަތް ތެރި، ޙޫރުލްޢީނުން އެ ސުވަރުގެތަކުގައިވެއެވެ. އެއުރެންގެ ކުރިން އިންސިއަކުވެސް، އަދި ޖިންނިއަކުވެސް އެކަނބަލުންގައި ބީހިފައެއް ނުވެއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","كأنهن الياقوت والمرجان","(ރީތިކަމާއި، ސާފުކަމުގައި) އެކަނބަލުން ޔާގޫތާއި، މަރުޖާން ފަދައެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","هل جزاء الإحسان إلا الإحسان","ހެޔޮކަމުގެ ޖަޒާއަކީ، ހެޔޮ ސަވާބުކަމުގައި މެނުވީ ވާނެހެއްޔެވެ؟","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","ومن دونهما جنتان","އަދި އެ ދެ ސުވަރުގެ ފިޔަވައި ދެ ސުވަރުގެވެއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","مدهامتان","(އެ ދެ ސުވަރުގޭގެ) ގަސްގަހުގެ ފަތްތައް ބޯވެ، ކަޅުފެހިކުލަ ލިބިގެންވެއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","فيهما عينان نضاختان","ފެން އަރައަރާ ހުންނަ ދެ އާރު، އެ ދެތާނގައިވެއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","فيهما فاكهة ونخل ورمان","އެ ދެތާނގައި މޭވާއާއި، ކަދުރުރުކާއި، އަދި އަންނާރު ވެއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަ ދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަ ދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","فيهن خيرات حسان","ހެޔޮކަން ބޮޑު، ރީތި އަނބީން އެތަންތާނގައިވެއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","حور مقصورات في الخيام","(އެއީ) ފޭލިގެތަކުގައި ފަރުދާވެވިގެންވާ ޙޫރު ންތަކެކެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","لم يطمثهن إنس قبلهم ولا جان","އެއުރެންގެ ކުރިން، އިންސިއަކުވެސް އަދި ޖިންނިއަކުވެސް އެކަނބަލުންގައި ބީހިފައެއް ނުވެއެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","متكئين على رفرف خضر وعبقري حسان","ފެހިކުލައިގެ ބާލީސްތަކުގައި ލެނގިލައިގެން، އަދި މަޚުމަލުގެ ގޮދަޑިތަކާއި، ރީތި ދޫލަތަކުގައި ތިބޭ ޙާލު ގައެވެ.","",""],["","","","فبأي آلاء ربكما تكذبان","(އޭ ޖިންނީންނާއި، އިންސީންނޭވެ!) ފަހެ، ތިޔަދެބައިމީހުން ދޮގުކޮށް އިންކާރުކުރަނީ، ތިޔަދެބައިމީހުންގެ ވެރިރަސްކަލާނގެ ނިއުމަތްތަކުގެ ތެރެއިން ކޮންކޮން ނިއުމަތަކަށް ހެއްޔެވެ؟","",""],["","","","تبارك اسم ربك ذي الجلال والإكرام","ކަލޭގެފާނުގެ ވެރި، ކީރިތިވަންތަކަމާއި، މާތްވަންތަކަމުގެ ވެރިރަސްކަލާނގެ އިސްމުފުޅު މަތިވެރިވެގެންވެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم إذا وقعت الواقعة","ގިޔާމަތް ވެއްޖެހިނދެވެ.","",""],["","","","ليس لوقعتها كاذبة","އެކަންވާނޭކަމާމެދު އިންކާރު ކޮށް ދޮގުކުރާނޭ ފަރާތެއް ނުވެއެވެ.","",""],["","","","خافضة رافعة","އެއްބަޔަކު ދަށްކުރަމުން، އަނެއްބަޔަކު މަތިކުރަމުންނެވެ. (އެބަހީ: އަބާއްޖަވެރިން ދަށްކުރައްވައި، ބާއްޖަވެރިން މަތިވެރިކުރައްވާ ދުވަހެއްގެ ގޮތުގައެވެ.)","",""],["","","","إذا رجت الأرض رجا","ބިންގަނޑު ގަދަފަދައަށް ހެލިގެންފިހިނދެވެ.","",""],["","","","وبست الجبال بسا","އަދި ފަރުބަދަތައް ފުނޑުފުނޑުވެ، ހިމުންވެއްޖެހިނދެވެ.","",""],["","","","فكانت هباء منبثا","ފަހެ، ވަޔާ ބުރަބުރައިގެންދާ ކުނޑިތަކެއްކަމުގައި އެ ފަރުބަދަތައް ވެއްޖެހިނދެވެ.","",""],["","","","وكنتم أزواجا ثلاثة","އަދި ތިޔަބައިމީހުން (އެދުވަހުން) ތިންބާވަތަކަށް ވެދެއެވެ.","",""],["","","","فأصحاب الميمنة ما أصحاب الميمنة","ފަހެ، ކަނާތްފަރާތުގެ މީހުންނެވެ. ކަނާތްފަރާތުގެ މީހުންނީ، ކޮންބަޔެއްހެއްޔެވެ؟","",""],["","","","وأصحاب المشأمة ما أصحاب المشأمة","އަދި ވާތްފަރާތުގެ މީހުންނެވެ. ވާތްފަރާތުގެ މީހުންނީ، (ދަރަޖައިގެގޮތުން) ކޮންބަޔެއްހެއްޔެވެ؟","",""],["","","","والسابقون السابقون","އަދި ކުރިއަރައިދިޔަ މީހުންނީ، (ދަރަޖައިގެގޮތުން) ކުރިއަރައިދިޔަ މީހުންނެވެ.","",""],["","","","أولئك المقربون","ކުއްތަންކުރައްވާފައިވާ މީހުންނީ، އެއުރެންނެވެ.","",""],["","","","في جنات النعيم","ނިއުމަތްގެ ސުވަރުގެތަކުގައެވެ.","",""],["","","","ثلة من الأولين","އިސްވެދިޔަމީހުންގެ ތެރެއިން (އެބަހީ: އިސްވެދިޔަ އުއްމަތްތަކުގެ މީހުންގެ ތެރެއިން) ގިނަބަޔެކެވެ.","",""],["","","","وقليل من الآخرين","އަދި ފަހުގެ މީހުންގެ ތެރެއިން (އެބަހީ: އިސްވެދިޔަ އުއްމަތް ތަކާ އަޅައިބަލާއިރު، މުޙައްމަދު ނަބިއްޔާގެ އުއްމަތްގެ މީހުންގެ ތެރެއިން) މަދުބަޔެކެވެ.","",""],["","","","على سرر موضونة","ރަނާއި، ޖަވާހިރުން އަތްކަން އަޅުއްވާފައިވާ ދާންތަކެއްގެ މަތީގައެވެ.","",""],["","","","متكئين عليها متقابلين","އެ ދާންތަކުގެ މަތީގައި، އެކަކު އަނެކަކާ ކުރިމަތިލައި، ލެނގިގެންވާ ޙާލު ގައެވެ.","",""],["","","","يطوف عليهم ولدان مخلدون","ޒުވާންކަންމަތީ ދެމިތިބޭ ޒުވާން ފިރިހެންކުދިން، އެއުރެންގެ ޚިދުމަތުގައި ބުރުޖަހާނެތެވެ.","",""],["","","","بأكواب وأباريق وكأس من معين","ތަށިތަކަކާއި، ކުރާތަކަކާއިގެންނެވެ. އަދި ހިނގަހިނގާ ހުންނަ އާރަކުން ނެގޭ ރާތަށިތަކަކާއިގެންނެވެ.","",""],["","","","لا يصدعون عنها ولا ينزفون","އޭގެސަބަބުން އެއުރެންނަށް ބޮލުގެ ރިހުމެއް ނުލިބޭނެތެވެ. އަދި މަސްތުވުމެއްވެސް ނުމެލިބޭނޭމެއެވެ.","",""],["","","","وفاكهة مما يتخيرون","އަދި އެއުރެން ބޭނުންގޮތަކަށް ނަގާނޭ މޭވާތަކާއިގެންނެވެ.","",""],["","","","ولحم طير مما يشتهون","އަދި އެއުރެން ހިތްއެދޭ ބާވަތްތަކުގެ ދޫނިސޫފާސޫފީގެ މަހާއިގެންނެވެ.","",""],["","","","وحور عين","އަދި ކަޅިރަވަ ރީތި، ޙޫރުލްޢީނުން ތިބޭނެއެވެ.","",""],["","","","كأمثال اللؤلؤ المكنون","(އެކަނބަލުން) ރައްކާތެރިކުރައްވާފައިވާ ރަންމުތްތަކަކާ އެއްފަދަވެގެންވެއެވެ.","",""],["","","","جزاء بما كانوا يعملون","(އެއީ) އެއުރެން ކޮށްއުޅުނު ޢަމަލުތަކަށް ޖަޒާއެއް ކަމުގައެވެ.","",""],["","","","لا يسمعون فيها لغوا ولا تأثيما","ބޭކާރު ބަސްތަކެއްވެސް، އަދި ކުށްވެރިކުރަނިވި ބަސްތަކެއްވެސް، އެތާކު އެއުރެންނަކަށް ނީވޭނެތެވެ.","",""],["","","","إلا قيلا سلاما سلاما","އެހެނެއްކަމަކު (އެއުރެންނަށް އިވޭނީ) ސަލާމް ހުށްޓޭ، ސަލާމް ހުށްޓޭ، ބުނެވޭ އަޑެވެ.","",""],["","","","وأصحاب اليمين ما أصحاب اليمين","ކަނާތްފަރާތުގެ މީހުންނެވެ. ކަނާތްފަރާތުގެ މީހުންނީ، ކޮންބަޔެއްހެއްޔެވެ؟","",""],["","","","في سدر مخضود","(އެއުރެންވަނީ) ކަށިނެތް، ކުންނާރު ގަސްތަކުގެ ތެރޭގައެވެ.","",""],["","","","وطلح منضود","ކެޔޮވައްތައް އެތުރިފައިވާ ފަތްކެޔޮ ގަސްތަކުގެ ތެރޭގައެވެ.","",""],["","","","وظل ممدود","އަދި ފެތުރިގެންވާ ހިޔަލުގައެވެ.","",""],["","","","وماء مسكوب","އަދި އަބަދަށް އޮހިއޮހިހުންނަ ފެން، އެއުރެންނަށް ލިބޭނެއެވެ.","",""],["","","","وفاكهة كثيرة","އަދި ގިނަގުނަވެގެންވާ މޭވާތައްވެސްމެއެވެ.","",""],["","","","لا مقطوعة ولا ممنوعة","ހުސްވުމެއްނުވާ، އަދި މަނާވުމެއްނުވާ މޭވާއެވެ.","",""],["","","","وفرش مرفوعة","އަދި އުފުލިގެންވާ ދާންތަކެވެ.","",""],["","","","إنا أنشأناهن إنشاء","ހަމަކަށަވަރުން، އަލުން އާ އުފެއްދެވުމަކުން ތިމަންރަސްކަލާނގެ އެކަނބަލުން (އެބަހީ: ސުވަރުގޭގެ އަންހެނުން) އުފެއްދެވީމެވެ.","",""],["","","","فجعلناهن أبكارا","ފަހެ، ބިކުރުވެރި ބަޔަކު ކަމުގައި ތިމަންރަސްކަލާނގެ އެކަނބަލުން ލެއްވީމެވެ.","",""],["","","","عربا أترابا","ފިރިންދެކެ ލޯބިވާ، އެއްފުރާގެ ބަޔަކު ކަމުގައެވެ.","",""],["","","","لأصحاب اليمين","ކަނާތްފަރާތުގެ މީހުންނަށްޓަކައެވެ.","",""],["","","","ثلة من الأولين","އިސްވެދިޔަ މީހުންގެ ތެރެއިން (އެބަހީ: އިސްވެދިޔަ އުއްމަތްތަކުގެ މީހުންގެ ތެރެއިން) ގިނަބަޔެކެވެ.","",""],["","","","وثلة من الآخرين","އަދި ފަހުގެ މީހުންގެ ތެރެއިންވެސް (އެބަހީ: މުޙައްމަދު ނަބިއްޔާގެ އުއްމަތްގެ މީހުންގެ ތެރެއިންވެސް) ގިނަބަޔެކެވެ.","",""],["","","","وأصحاب الشمال ما أصحاب الشمال","ވާތްފަރާތުގެ މީހުންނެވެ. ވާތްފަރާތުގެ މީހުންނީ، ކޮންބަޔެއްހެއްޔެވެ؟","",""],["","","","في سموم وحميم","(އެއުރެންވަނީ، ލޯލިތަކުގެ ބުޑުތައް ފޫވައްޓައިފަނިވި) ހޫނު ވައިގެތެރޭގައެވެ. އަދި ކެކިކެކިހުންނަ ހޫނުފެނުގެ ތެރޭގައެވެ.","",""],["","","","وظل من يحموم","އަދި ކަޅުކުލައިގެ ދުމަކުން އުފެދޭ ހިޔަނިގަނޑެއްގެ ތެރޭގައެވެ.","",""],["","","","لا بارد ولا كريم","ފިންޏެއްވެސް ނޫނެވެ. އަދި އަރާމެއްވެސް ނޫނެވެ.","",""],["","","","إنهم كانوا قبل ذلك مترفين","ހަމަކަށަވަރުން، އޭގެކުރިން އެއުރެންވީ، ތަނަވަސްކަމުގައި ހައްދުފަހަނަޅައިފައިވާ ބަޔަކު ކަމުގައެވެ.","",""],["","","","وكانوا يصرون على الحنث العظيم","އަދި ބޮޑުވެގެންވާ ފާފަވެރިކަމުގެ މަތީގައި ދެމިތިބޭ ބަޔަކުކަމުގައި އެއުރެންވޫއެވެ.","",""],["","","","وكانوا يقولون أئذا متنا وكنا ترابا وعظاما أإنا لمبعوثون","އަދި އެއުރެން ބުނާކަމުގައިވިއެވެ. ތިމަންމެން މަރުވެ، ވެއްޔަށާއި ކަށިތަކަކަށް ވެއްޖެހިނދު، އަލުން ދިރުމަކަށް ފޮނުއްވާނޭ ބަޔަކުކަމުގައި ހަމަކަށަވަރުން، ތިމަންމެން ވޭހެއްޔެވެ؟","",""],["","","","أوآباؤنا الأولون","އަދި ތިމަންމެންގެ އިސްވެދިޔަ ކާބަފައިންވެސް ހެއްޔެވެ؟","",""],["","","","قل إن الأولين والآخرين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، އިސްވެދިޔަ މީހުންނާއި، ފަހުން އަންނާނޭ މީހުންނީ، އެނގިގެންވާ ދުވަހެއްގެ ކަނޑައަޅުއްވާފައިވާ ވަގުތަކަށް އެއްކުރައްވާނޭ ބަޔަކުކަން ކަށަވަރެވެ.","",""],["","","","لمجموعون إلى ميقات يوم معلوم","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، އިސްވެދިޔަ މީހުންނާއި، ފަހުން އަންނާނޭ މީހުންނީ، އެނގިގެންވާ ދުވަހެއްގެ ކަނޑައަޅުއްވާފައިވާ ވަގުތަކަށް އެއްކުރައްވާނޭ ބަޔަކުކަން ކަށަވަރެވެ.","",""],["","","","ثم إنكم أيها الضالون المكذبون","އޭ މަގުފުރެދިގެންވާ، އަދި ދޮގުކުރާ މީހުންނޭވެ! ދެން ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ޒައްގޫމު ގަހުން ކާނޭކަން ކަށަވަރެވެ.","",""],["","","","لآكلون من شجر من زقوم","އޭ މަގުފުރެދިގެންވާ، އަދި ދޮގުކުރާ މީހުންނޭވެ! ދެން ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ޒައްގޫމު ގަހުން ކާނޭކަން ކަށަވަރެވެ.","",""],["","","","فمالئون منها البطون","ފަހެ، އެއިން ބަނޑުތައް ފުރައިލާނޭމެއެވެ.","",""],["","","","فشاربون عليه من الحميم","ފަހެ، އޭގަމައްޗަށް ކެކިކެކިހުންނަ ހޫނުފެން ބޯނޭމެއެވެ.","",""],["","","","فشاربون شرب الهيم","ފަހެ، ފެންބޮވައިގެންފައިވާ ޖަމަލުތައް ފެންބޯފަދައިންނެވެ.","",""],["","","","هذا نزلهم يوم الدين","ގިޔާމަތް ދުވަހުން އެއުރެންގެ މެހުމާންދާރީއަކީ މިއެވެ.","",""],["","","","نحن خلقناكم فلولا تصدقون","ތިޔަބައިމީހުން ހެއްދެވީ ތިމަންރަސްކަލާނގެއެވެ. ފަހެ ތިޔަބައިމީހުން ތެދުނުކުރަނީ ކީއްވެހެއްޔެވެ؟","",""],["","","","أفرأيتم ما تمنون","ތިޔަބައިމީހުން ބޭރުކުރާ މަންޏާމެދު، ތިޔަބައިމީހުން ފަހެ، ވިސްނައި ބެލީމުހެއްޔެވެ؟","",""],["","","","أأنتم تخلقونه أم نحن الخالقون","އެތަކެތި ހަދަނީ، ތިޔަބައިމީހުން ހެއްޔެވެ؟ ނުވަތަ ހައްދަވާ ފަރާތަކީ ތިމަންރަސްކަލާނގެ ހެއްޔެވެ؟","",""],["","","","نحن قدرنا بينكم الموت وما نحن بمسبوقين","ތިޔަބައިމީހުންގެ މެދުގައި ތިމަންރަސްކަލާނގެ މަރު، މިންވަރުކުރެއްވީމެވެ. ތިޔަބައިމީހުންގެ ބަދަލުގައި، ތިޔަބައިމީހުންފަދަ އެހެންބަޔަކު ގެންނެވުމުގެ މައްޗަށާއި، ތިޔަބައިމީހުން ނުދަންނަ ސިފައެއްގައި، ތިޔަބައިމީހުން އަލުން އުފެއްދެވުމަށް ނުކުޅެދިގެންވާ ކަލަކުކަމުގައި ތިމަންރަސްކަލާނގެ ނުވަމެވެ.","",""],["","","","على أن نبدل أمثالكم وننشئكم في ما لا تعلمون","ތިޔަބައިމީހުންގެ މެދުގައި ތިމަންރަސްކަލާނގެ މަރު، މިންވަރުކުރެއްވީމެވެ. ތިޔަބައިމީހުންގެ ބަދަލުގައި، ތިޔަބައިމީހުންފަދަ އެހެންބަޔަކު ގެންނެވުމުގެ މައްޗަށާއި، ތިޔަބައިމީހުން ނުދަންނަ ސިފައެއްގައި، ތިޔަބައިމީހުން އަލުން އުފެއްދެވުމަށް ނުކުޅެދިގެންވާ ކަލަކުކަމުގައި ތިމަންރަސްކަލާނގެ ނުވަމެވެ.","",""],["","","","ولقد علمتم النشأة الأولى فلولا تذكرون","ހަމަކަށަވަރުން، ފުރަތަމަ އުފެއްދެވުން ތިޔަބައިމީހުންނަށް އެނގިފައިވެއެވެ. ފަހެ، ތިޔަބައިމީހުން ހަނދުމަނުކުރަނީ ކީއްވެހެއްޔެވެ؟","",""],["","","","أفرأيتم ما تحرثون","ތިޔަބައިމީހުން ގޮވާންކުރާ ތަކެއްޗާމެދު، ފަހެ، ތިޔަބައިމީހުން ވިސްނައި ބެލީމުހެއްޔެވެ؟","",""],["","","","أأنتم تزرعونه أم نحن الزارعون","އެތަކެތި ބިމުން ފަޅުވަނީ، ތިޔަބައިމީހުންހެއްޔެވެ؟ ނުވަތަ އެތަކެތި ބިމުން ފަޅުއްވާ ފަރާތަކީ، ތިމަންރަސްކަލާނގެ ހެއްޔެވެ؟","",""],["","","","لو نشاء لجعلناه حطاما فظلتم تفكهون","ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާނަމަ، ހިކި ކުނޑި ހުއިތަކެއް ކަމުގައި އެތަކެތި ލައްވައިފީމުސްކަން ކަށަވަރެވެ. ދެން އެކަމާމެދު ތިޔަބައިމީހުން ހައިރާން ވެފައި ތިބެއްޖައީހެވެ.","",""],["","","","إنا لمغرمون","(ތިޔަބައިމީހުން ބުނާނޫއެވެ.) ހަމަކަށަވަރުން، ތިމަންމެންނީ، ގެއްލުންވެގެންވާ ބަޔަކީމުއެވެ.","",""],["","","","بل نحن محرومون","އަދި ކިއެއްތަ! ތިމަންމެންނީ (އެތަކެތިން) މަޙްރޫމު ވެގެންވާ ބަޔަކީމުއެވެ.","",""],["","","","أفرأيتم الماء الذي تشربون","ތިޔަބައިމީހުން ބޯ ފެނާމެދު، ތިޔަބައިމީހުން ފަހެ ވިސްނާ ބެލީމުހެއްޔެވެ؟","",""],["","","","أأنتم أنزلتموه من المزن أم نحن المنزلون","ވާރޭވިލާތަކުން އެ ފެން ވެއްސީ، ތިޔަބައިމީހުންހެއްޔެވެ؟ ނުވަތަ އެ ފެން ބާވައިލެއްވި ފަރާތަކީ، ތިމަންރަސްކަލާނގެ ހެއްޔެވެ؟","",""],["","","","لو نشاء جعلناه أجاجا فلولا تشكرون","ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވާނަމަ، އެ ފެން ބޯން ނުކެރޭފަދަ ލޮނު ފެނެއް ކަމުގައި ލައްވައިފީމުހެވެ. ފަހެ، ތިޔަބައިމީހުން ޝުކުރު ނުކުރަނީ ކީއްވެހެއްޔެވެ؟","",""],["","","","أفرأيتم النار التي تورون","ތިޔަބައިމީހުން ރޯކުރާ އަލިފާނާމެދު، ތިޔަބައިމީހުން ފަހެ، ވިސްނައި ބެލީމުހެއްޔެވެ؟","",""],["","","","أأنتم أنشأتم شجرتها أم نحن المنشئون","އޭގެ ގަސް އުފެއްދީ ތިޔަބައިމީހުން ހެއްޔެވެ؟ ނުވަތަ އެ އުފެއްދެވި ފަރާތަކީ ތިމަންރަސްކަލާނގެ ހެއްޔެވެ؟","",""],["","","","نحن جعلناها تذكرة ومتاعا للمقوين","ހަނދުމަކުރުމެއް ކަމުގައްޔާއި، ދަތުރުފަތުރުކުރާ މީހުންނަށާއި، ދަތުރުނުކޮށް ގާއިމު ވެތިބޭ މީހުންނަށް ބޭނުންހިފޭ އެއްޗެއްކަމުގައި، ތިމަންރަސްކަލާނގެ އެ އަލިފާން ލެއްވީމެވެ.","",""],["","","","فسبح باسم ربك العظيم","ފަހެ، ކަލޭގެފާނުގެ ވެރި، މާތްވަންތަ ރަސްކަލާނގެ އިސްމުފުޅުން ކަލޭގެފާނު ތަސްބީހަ ވިދާޅުވާށެވެ!","",""],["","","","فلا أقسم بمواقع النجوم","ފަހެ، ހަމަކަށަވަރުން، ތަރިތައް އޮސްފުހޭ ތަންތަން ގަންދެއްވައި ތިމަންރަސްކަލާނގެ ހުވާ ވަހީކުރައްވަމެވެ.","",""],["","","","وإنه لقسم لو تعلمون عظيم","އަދި ތިޔަބައިމީހުން ދަންނަނީނަމަ، ހަމަކަށަވަރުން، އެއީ ބޮޑުވެގެންވާ ހުވަޔެއްކަން ކަށަވަރެވެ.","",""],["","","","إنه لقرآن كريم","ހަމަކަށަވަރުން، އެއީ މާތްވެގެންވާ ގުރްއާން ކަން ކަށަވަރެވެ.","",""],["","","","في كتاب مكنون","ރައްކާތެރިކުރައްވާފައިވާ ފޮތެއްގައެވެ.","",""],["","","","لا يمسه إلا المطهرون","ތާހިރު ވެގެންވާ މީހުން މެނުވީ، އެ ފޮތުގައި ނުބީހޭނެތެވެ.","",""],["","","","تنزيل من رب العالمين","(އެއީ) އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ބާވައިލެއްވި ފޮތެކެވެ.","",""],["","","","أفبهذا الحديث أنتم مدهنون","ތިޔަބައިމީހުން ދޮގުކޮށް ފަރުވާކުޑަކުރަނީ، މިވާހަކައާމެދުގައި (އެބަހީ: މި ގުރްއާނާ މެދުގައި) ހެއްޔެވެ؟","",""],["","","","وتجعلون رزقكم أنكم تكذبون","އަދި ތިޔަބައިމީހުންނަށް ރިޒްގު ދެއްވިކަމުގެ މައްޗަށްކުރާ ޝުކުރަކީ (އެ ރިޒްގު ދެއްވި ރަސްކަލާނގެ) ދޮގުކުރުން ކަމުގައި ތިޔަބައިމީހުން ހަދަމުއެވެ.","",""],["","","","فلولا إذا بلغت الحلقوم","ފަހެ، މަރުވުމުގެ ވަގުތުގައި، ކަރާހަމަޔަށް ފުރާނައައިސް ނޭވާހޮޅިޔަށް އެޅިއްޖެހިނދެވެ.","",""],["","","","وأنتم حينئذ تنظرون","އަދި އެހިނދު، ތިޔަބައިމީހުން ބަލަބަލައި ތިބެމުއެވެ.","",""],["","","","ونحن أقرب إليه منكم ولكن لا تبصرون","އަދި ތިޔަބައިމީހުންނަށްވުރެ އެމީހާއާ (އެބަހީ: މަރުވާ މީހާއާ) ގާތްކަންބޮޑީ، ތިމަންރަސްކަލާނގެއެވެ. އެހެނެއްކަމަކު، ތިޔަބައިމީހުންނަކަށް ނުފެނެތެވެ.","",""],["","","","فلولا إن كنتم غير مدينين","ފަހެ، ތިޔަބައިމީހުންނީ، ޢަމަލުތަކަށް ޖަޒާ ނުލިބޭނެ ބަޔަކުކަމުގައިވާނަމަ، ތިޔަބައިމީހުން އެ ފުރާނަ އަނބުރައި ނުގެންނަނީ ކީއްވެގެން ހެއްޔެވެ؟ ތިޔަބައިމީހުންނީ، ތެދުވެރިން ކަމުގައިވާނަމައެވެ.","",""],["","","","ترجعونها إن كنتم صادقين","ފަހެ، ތިޔަބައިމީހުންނީ، ޢަމަލުތަކަށް ޖަޒާ ނުލިބޭނެ ބަޔަކުކަމުގައިވާނަމަ، ތިޔަބައިމީހުން އެ ފުރާނަ އަނބުރައި ނުގެންނަނީ ކީއްވެގެން ހެއްޔެވެ؟ ތިޔަބައިމީހުންނީ، ތެދުވެރިން ކަމުގައިވާނަމައެވެ.","",""],["","","","فأما إن كان من المقربين","ފަހެ، އެ (މަރުވި) މީހާ ކުއްތަންކުރައްވާފައިވާ މީހުންގެ ތެރެއިންވާނަމަ، ދަންނާށެވެ!","",""],["","","","فروح وريحان وجنت نعيم","ފަހެ، އެމީހަކަށް އަރާމާއި، ތަނަވަސްވެގެންވާ ރިޒްގާއި، ނިއުމަތްގެ ސުވަރުގެ ހުށްޓެވެ.","",""],["","","","وأما إن كان من أصحاب اليمين","އަދި އެމީހަކު ކަނާތްފަރާތުގެ މީހުންގެ ތެރެއިންވާނަމަ، ދަންނާށެވެ!","",""],["","","","فسلام لك من أصحاب اليمين","ފަހެ، (އެމީހަކަށް އަންގަވާނެތެވެ.) ކަނާތްފަރާތުގެ މީހުންގެ ކިބައިން ތިބާޔަށް ސަލާމް ހުށްޓެވެ.","",""],["","","","وأما إن كان من المكذبين الضالين","އަދި ދޮގުކޮށް، މަގުފުރެދޭ މީހުންގެ ތެރެއިން އެމީހަކުވާނަމަ، ދަންނާށެވެ!","",""],["","","","فنزل من حميم","ފަހެ، އެމީހަކަށްހުރީ، ކެކިކެކިހުންނަ ހޫނުފެނުގެ މެހުމާންދާރީއެކެވެ.","",""],["","","","وتصلية جحيم","އަދި ނަރަކަޔަށް ވެއްދެވުމެކެވެ.","",""],["","","","إن هذا لهو حق اليقين","ހަމަކަށަވަރުން، މިއީ ޔަގީން ވެގެންވާ ހައްގު ތެދުކަން ކަށަވަރެވެ.","",""],["","","","فسبح باسم ربك العظيم","ފަހެ، ކަލޭގެފާނު ގެ ވެރި، މާތްވަންތަ ރަސްކަލާނގެ އިސްމުފުޅުން ކަލޭގެފާނު ތަސްބީހަ ވިދާޅުވާށެވެ!","",""],["","","","بسم الله الرحمن الرحيم سبح لله ما في السماوات والأرض وهو العزيز الحكيم","އުޑުތަކާއި، ބިމުގައިވާހާ ތަކެއްޗެއް، ﷲއަށް ތަސްބީހަ ކިޔައިފިއެވެ. އަދި އެކަލާނގެއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","له ملك السماوات والأرض يحيي ويميت وهو على كل شيء قدير","އުޑުތަކާއި، ބިމުގެ ވެރިކަން މަލަކަ ވެގެންވަނީ، އެކަލާނގެއަށެވެ. ދިރުއްވަނީވެސް، އަދި މަރުގަންނަވަނީވެސް، އެކަލާނގެއެވެ. އަދި އެކަލާނގެއީ، ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","هو الأول والآخر والظاهر والباطن وهو بكل شيء عليم","އެކަލާނގެއީ، (ފެށުމެއްނެތި) އިސްވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އަދި (ނިމުމެއްނެތި) ފަސްވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އަދި (ހެކިތަކުން) ފާޅުވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އަދި (ޙިއްސުތަކަށް) ވަންހަނާވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެއީ، ކޮންމެކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","هو الذي خلق السماوات والأرض في ستة أيام ثم استوى على العرش يعلم ما يلج في الأرض وما يخرج منها وما ينزل من السماء وما يعرج فيها وهو معكم أين ما كنتم والله بما تعملون بصير","އެކަލާނގެއީ، އުޑުތަކާއި، ބިން، ހަ ދުވަހުގެ ތެރޭގައި ހެއްދެވި ރަސްކަލާނގެއެވެ. ދެން އެކަލާނގެ ޢަރްޝުގެ މައްޗަށް އިސްތިވާ ވެވޮޑިގަތެވެ. ބިމުގެތެރެޔަށް ވަންނަ ތަކެއްޗާއި، އެ ބިމުން ނުކުންނަ ތަކެއްޗާއި، އުޑުން ފައިބާ އެއްޗަކާއި، އެ އުޑަށް އަރައިގެންދާ އެއްޗެއް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަދި ތިޔަބައިމީހުންވީ ކޮންމެތަނެއްގައި، ތިޔަބައިމީހުންނާއެކު، އެކަލާނގެ ވޮޑިގެންވެތެވެ. އަދި ﷲއީ، ތިޔަބައިމީހުން ކުރާ ޢަމަލުތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","له ملك السماوات والأرض وإلى الله ترجع الأمور","އުޑުތަކާއި، ބިމުގެ ވެރިކަން މިލްކުވެގެންވަނީ، އެކަލާނގެއަށެވެ. އަދި އެންމެހާ ކަންތައް ރުޖޫއަކުރައްވާހުށީ، ﷲގެ ހަޒުރަތަށެވެ.","",""],["","","","يولج الليل في النهار ويولج النهار في الليل وهو عليم بذات الصدور","އެކަލާނގެ، ދުވާލުގެ ތެރެޔަށް ރޭގަނޑު ވައްދަވަތެވެ. އަދި ރޭގަނޑުގެ ތެރެޔަށް ދުވާލު ވައްދަވަތެވެ. އަދި އެކަލާނގެއީ، ހިތްތަކުގައި ވާހާކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","آمنوا بالله ورسوله وأنفقوا مما جعلكم مستخلفين فيه فالذين آمنوا منكم وأنفقوا لهم أجر كبير","ﷲއާއި، އެކަލާނގެ ރަސޫލާއަށް ތިޔަބައިމީހުން އީމާން ވާށެވެ! އަދި އެތަކެއްޗާމެދު، އެކަލާނގެ ތިޔަބައިމީހުން ޚަލީފާވެރިންކަމުގައި ލެއްވި ތަކެތިން ތިޔަބައިމީހުން ހޭދަކުރާށެވެ! ފަހެ، ތިޔަބައިމީހުންގެ ތެރެއިން އީމާންވެ، އަދި ހޭދަކުރިމީހުން ދަންނާށެވެ! އެއުރެންނަށް ބޮޑުވެގެންވާ ދަރުމަހުށްޓެވެ.","",""],["","","","وما لكم لا تؤمنون بالله والرسول يدعوكم لتؤمنوا بربكم وقد أخذ ميثاقكم إن كنتم مؤمنين","ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެއަށް އީމާން ވުމަށް ރަސޫލާ ތިޔަބައިމީހުންނަށް ގޮވައިލައްވާ ޙާލު، ތިޔަބައިމީހުން ﷲއަށް އީމާން ނުވާންވީ ކީއްވެގެން ހެއްޔެވެ؟ އަދި ހަމަކަށަވަރުން، އެކަލާނގެ ތިޔަބައިމީހުންގެ (ކިބައިން) ކަށަވަރުވެގެންވާ އަހުދު ހިއްޕަވާފައިވެއެވެ. ތިޔަބައިމީހުންނީ، މުއުމިނުން ކަމުގައި ވާނަމައެވެ.","",""],["","","","هو الذي ينزل على عبده آيات بينات ليخرجكم من الظلمات إلى النور وإن الله بكم لرءوف رحيم","އެކަލާނގެއީ، ބަޔާންވެގެންވާ އާޔަތް ތަކެއް، އެކަލާނގެ އަޅާގެ މައްޗަށް ބާވައިލައްވާ ރަސްކަލާނގެއެވެ. (އެއީ) އަނދިރިކަމުގެ ތެރެއިން އަލިކަމުގެ ތެރެއަށް ތިޔަބައިމީހުން ނެރުއްވުމަށްޓަކައެވެ. އަދި ހަމަކަށަވަރުން، ﷲއީ، ތިޔަބައިމީހުންނާމެދު ނުހަނު އޯގާވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","وما لكم ألا تنفقوا في سبيل الله ولله ميراث السماوات والأرض لا يستوي منكم من أنفق من قبل الفتح وقاتل أولئك أعظم درجة من الذين أنفقوا من بعد وقاتلوا وكلا وعد الله الحسنى والله بما تعملون خبير","އަދި ﷲގެ މަގުގައި ތިޔަބައިމީހުން ހޭދަނުކުރާންވީ ކީއްވެގެން ހެއްޔެވެ؟ އުޑުތަކާއި، ބިމުގެ މިލްކުވެރިކަންވަނީ ﷲއަށެވެ. (މައްކާ) ފަތަޙަ ވުމުގެކުރިން ތިޔަބައިމީހުންގެ ތެރެއިން ހޭދަކޮށް، އަދި ހަނގުރާމަކޮށް އުޅުނުމީހުން (އެނޫން މީހުންނާ) ހަމަހަމަވެގެނެއް ނުވެތެވެ. އޭގެފަހުން ހޭދަކޮށް، އަދި ހަނގުރާމަ ކުޅަމީހުންނަށްވުރެން ދަރަޖައިގެގޮތުން އެއުރެން (އެބަހީ: މައްކާ ފަތަޙަކުރެއްވުމުގެކުރިން ހޭދަކުރިމީހުން) މާ މާތްކަންބޮޑެވެ. ކޮންމެ ބަޔަކަށްމެ ހެޔޮދަރުމަ، ﷲ ވައުދުކުރައްވާފައިވެއެވެ. އަދި ﷲއީ، ތިޔަބައިމީހުން ކުރާ ޢަމަލުތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","من ذا الذي يقرض الله قرضا حسنا فيضاعفه له وله أجر كريم","ހެޔޮވެގެންވާ ދަރަންޏަކުން ﷲއަށް ދަރަނިދޭހުށީ (އެބަހީ: ﷲއަށްޓަކައި ހޭދަކުރާހުށީ) ކާކުހެއްޔެވެ؟ ފަހެ، އެމީހަކަށްޓަކައި (އެކަމުގެ) ދަރުމަ، އެކަލާނގެ ގިނަގުނަކުރައްވާނެތެވެ. އަދި އެމީހަކަށް ދީލަތިވެގެންވާ ދަރުމަހުށްޓެވެ.","",""],["","","","يوم ترى المؤمنين والمؤمنات يسعى نورهم بين أيديهم وبأيمانهم بشراكم اليوم جنات تجري من تحتها الأنهار خالدين فيها ذلك هو الفوز العظيم","މުއުމިނު ފިރިހެނުންނާއި، މުއުމިނު އަންހެނުން، ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނޭ ދުވަހު، އެއުރެންގެ ކުރިމަތިންނާއި، އެއުރެންގެ ކަނާތްފަރާތުން، އެއުރެންގެ ނޫރު ހިނގަހިނގާ ހުންނާނެތެވެ. (އަދި އެއުރެންނަށް އަންގަވާނެތެވެ.) މިއަދު ތިޔަބައިމީހުންނަށް އުފާވެރިކަމުގެ ޚަބަރު ހުށްޓެވެ. (އެއީ) އެތަންތާނގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކެވެ. އެތަންތާނގައި އެއުރެން ދެމިތިބެނިވި ގޮތުގައެވެ. ބޮޑުވެގެންވާ ނަސީބު ލިބުމަކީ ހަމައެއީއެވެ.","",""],["","","","يوم يقول المنافقون والمنافقات للذين آمنوا انظرونا نقتبس من نوركم قيل ارجعوا وراءكم فالتمسوا نورا فضرب بينهم بسور له باب باطنه فيه الرحمة وظاهره من قبله العذاب","(އެއީ) މުނާފިގު ފިރިހެނުންނާއި، މުނާފިގު އަންހެނުން، އީމާންވި މީހުންނަށް ބުނާދުވަހެވެ. ތިޔަބައިމީހުންގެ ނޫރުން ތިމަންމެން އަލިކަމެއް ލިބިގަތުމަށްޓަކައި ތިޔަބައިމީހުން ތިމަންމެންނަށް އިންތިޒާރުކުރާށެވެ! އަންގަވާނެތެވެ. ތިޔަބައިމީހުންގެ ފަހަތަށް ތިޔަބައިމީހުން އެނބުރި ހިނގައިދާށެވެ! ފަހެ، ތިޔަބައިމީހުން (އެހެން) ނޫރަކަށް އެދޭށެވެ! ފަހެ، އެ އުރެންގެ މެދުގައި ފާރެއް ލައްވާނެތެވެ. އެ ފާރުގައި ދޮރެއްވެއެވެ. އޭގެ އެތެރެފުށުގައިވަނީ ރަހުމަތެވެ. އަދި އޭގެ ބޭރުފުށުން އަނެއްފަރާތުގައިވަނީ އަޒާބެވެ.","",""],["","","","ينادونهم ألم نكن معكم قالوا بلى ولكنكم فتنتم أنفسكم وتربصتم وارتبتم وغرتكم الأماني حتى جاء أمر الله وغركم بالله الغرور","އެއުރެން (އެބަހީ: މުނާފިގުން) އަނެއްބައި މީހުންނަށް ގޮވައި އުޅޭނެތެވެ. ތިމަންމެން ތިޔަބައިމީހުންނާ އެކުގައި ނުވަމުހެއްޔެވެ؟ އެއުރެން (އެބަހީ: މުއުމިނުން) ބުނާނެތެވެ. ނޫނެކެވެ. އެހެނެއްކަމަކު، ތިޔަބައިމީހުން، ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތައް ފިތުނަވެރިކޮށް، ހަލާކުކުޅައީމުއެވެ. އަދި (މުއުމިނުންނަށް ދެރަލިބުމަށް) ތިޔަބައިމީހުން އިންތިޒާރުކުޅައީމުއެވެ. އަދި ތިޔަބައިމީހުން ޝައްކުކުޅައީމުއެވެ. އަދި ދޮގު އުންމީދުތައް ތިޔަބައިމީހުން ހެއްލުންތެރި ކުޅައެވެ. ﷲގެ އަމުރުފުޅު އަތުވެއްޖައުމަށް ދާނދެނެވެ. އަދި ﷲއާމެދު ޝައިތާނާ ތިޔަބައިމީހުން ހެއްލުންތެރިކުޅައެވެ.","",""],["","","","فاليوم لا يؤخذ منكم فدية ولا من الذين كفروا مأواكم النار هي مولاكم وبئس المصير","ފަހެ، މިއަދު ތިޔަބައިމީހުންގެ ކިބަޔަކުން އަދި ކާފިރު ވިމީހުންގެ ކިބަޔަކުންވެސް ފިދުޔެއް އަތުނުލައްވާހުށްޓެވެ. ތިޔަބައިމީހުން ތިބެނިވިތަނަކީ ނަރަކަޔެވެ. ތިޔަބައިމީހުންގެ އެހީތެރި ފަރާތަކީވެސް އެއީއެވެ. އަދި އެއީ ހާދަހާ ނުބައިވެގެންވާ ނިމިދިޔުމެކެވެ.","",""],["","","","ألم يأن للذين آمنوا أن تخشع قلوبهم لذكر الله وما نزل من الحق ولا يكونوا كالذين أوتوا الكتاب من قبل فطال عليهم الأمد فقست قلوبهم وكثير منهم فاسقون","ﷲ ހަނދުމަކުރުމަށާއި، ހައްގު ބަސްފުޅުގެ ތެރެއިން ބާވައިލެއްވި ފޮތަށް އެއުރެންގެ ހިތްތައް މަޑުމައިތިރިވުމަށާއި، މީގެކުރިން ފޮތް ލިބުނު މީހުން ފަދައިން ނުވުމަށް، އީމާންވި މީހުންނަށް އަދިވެސް ވަގުތު ނާންނަނީހެއްޔެވެ؟ ފަހެ، އެއުރެންނަށް ޒަމާން ދިގުވެގެންދިޔައެވެ. ދެން (އެކަމުގެ ސަބަބުން) އެއުރެންގެ ހިތްތައް ހަރުކަށިވިއެވެ. އަދި އެއުރެންކުރެ ގިނަމީހުންނީ ފާސިގުންނެވެ.","",""],["","","","اعلموا أن الله يحيي الأرض بعد موتها قد بينا لكم الآيات لعلكم تعقلون","ބިންގަނޑު މަރުވެ އޮތުމަށްފަހު، ހަމަކަށަވަރުން، ﷲ އެ ބިންގަނޑު ދިރުއްވާކަން ތިޔަބައިމީހުން ދަންނާށެވެ! ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށްޓަކައި އާޔަތްތައް ބަޔާންކޮށްދެއްވީމެވެ. (އެއީ) ތިޔަބައިމީހުން ވިސްނުމަށްޓަކައެވެ.","",""],["","","","إن المصدقين والمصدقات وأقرضوا الله قرضا حسنا يضاعف لهم ولهم أجر كريم","ހަމަކަށަވަރުން، ސަދަގާތްކުރާ ފިރިހެނުންނާއި، ސަދަގާތްކުރާ އަންހެނުންނާއި، އަދި ހެޔޮވެގެންވާ ދަރަނި ދިނުމަކުން ﷲއަށްޓަކައި ދަރަނި ދިން (އެބަހީ: ﷲއަށްޓަކައި ހޭދަކުރި) މީހުން (ދަންނާށެވެ!) އެއުރެންނަށް (އެކަންކަމުގެ) ދަރުމަ ގިނަގުނަ ކުރައްވާނެތެވެ. އަދި އެއުރެންނަށް ދީލަތިވެގެންވާ ދަރުމަ ހުށްޓެވެ.","",""],["","","","والذين آمنوا بالله ورسله أولئك هم الصديقون والشهداء عند ربهم لهم أجرهم ونورهم والذين كفروا وكذبوا بآياتنا أولئك أصحاب الجحيم","ﷲއާއި، އެކަލާނގެ ރަސޫލުންނަށް އީމާން ވިމީހުން (ދަންނާށެވެ!) އެއުރެންނީ އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ޞިއްދީގްނާއި، ޝަހީދުންނެވެ. އެއުރެންގެ ދަރުމައާއި، އެއުރެންގެ ނޫރު، އެއުރެންނަށް ހުށްޓެވެ. އަދި ކާފިރުވެ، ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުޅަމީހުން (ދަންނާށެވެ!) އެއުރެންނީ ނަރަކައިގެ އަހުލުވެރިންނެވެ.","",""],["","","","اعلموا أنما الحياة الدنيا لعب ولهو وزينة وتفاخر بينكم وتكاثر في الأموال والأولاد كمثل غيث أعجب الكفار نباته ثم يهيج فتراه مصفرا ثم يكون حطاما وفي الآخرة عذاب شديد ومغفرة من الله ورضوان وما الحياة الدنيا إلا متاع الغرور","ތިޔަބައިމީހުން ދަންނާށެވެ! ދުނިޔޭގެ ދިރިއުޅުން ވާކަން ކަށަވަރީ ކުޅިވަރެއް ކަމުގައެވެ. އަދި މަޖަލެއް ކަމުގައެވެ. އަދި ޒީނަތެއް ކަމުގައެވެ. އަދި ތިޔަބައިމީހުންގެ މެދުގައި އެކަކު އަނެކަކުގެ މައްޗަށް ބޮޑާވެގަތުމެއް ކަމުގައެވެ. އަދި މުދާތަކާއި، ދަރިންތަކާމެދު، އެކަކު އަނެކަކަށްވުރެ ގިނަކަމަށްބުނެ މޮޅުވާހަކަ ދެއްކުމެއް ކަމުގައެވެ. ވާރޭފެނެއްގެ މިސާލުގައެވެ. އެ ފެނުން ފެންލިބިގެން ފެޅި ގަސްތަކެއް، ދަނޑުވެރިން އަޖާއިބު ކޮށްފައިވެއެވެ. ދެން އެ ގަސްތައް ހިކިދެއެވެ. ދެން އެ ގަހުގެ ފަތްތައް ރީނދޫވެފައި ވަނިކޮށް ތިބާއަށް ފެންނާނެތެވެ. ދެން އެ ހިކި ހުއިތަކަކަށް ވެދެއެވެ. އަދި އާޚިރަތް ގައިވަނީ، ގަދަފަދަވެގެންވާ އަޒާބެވެ. އަދި ﷲގެ ހަޒުރަތުން ލިބޭ ފާފަފުއްސެވުމަކާއި، ރުއްސެވުމެކެވެ. ކެހިވެރިކަމުގެ ވަގުތީ އުފަލެއްދޭ އެއްޗެއް ކަމުގައި މެނުވީ ދުނިޔޭގެ ދިރިއުޅުން ނުވެތެވެ.","",""],["","","","سابقوا إلى مغفرة من ربكم وجنة عرضها كعرض السماء والأرض أعدت للذين آمنوا بالله ورسله ذلك فضل الله يؤتيه من يشاء والله ذو الفضل العظيم","ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ފާފަފުއްސެވުން ލިބިގަތުމަށާއި، އެތާނގެ ތަނަވަސްކަން އުޑާއި ބިމުގެ ތަނަވަސްކަންފަދަ ސުވަރުގެޔަށް ތިޔަބައިމީހުން ކުރިއަރައިދާށެވެ! އެ ސުވަރުގެ ތައްޔާރު ކުރައްވާފައިވަނީ، ﷲއަށާއި، އެކަލާނގެ ރަސޫލުންނަށް އީމާންވި މީހުންނަށްޓަކައެވެ. އެއީ ﷲގެ ފަޟްލު ވަންތަކަމެވެ. އެކަލާނގެ އިރާދަކުރައްވާ އަޅަކަށް އެ ފަޟްލު ވަންތަކަން ދެއްވަތެވެ. ﷲއީ، ބޮޑުވެގެންވާ ފަޟްލު ވަންތަކަމުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["","","","ما أصاب من مصيبة في الأرض ولا في أنفسكم إلا في كتاب من قبل أن نبرأها إن ذلك على الله يسير","އެއްވެސް މުސީބަތެއް، ތިމަންރަސްކަލާނގެ އެ މުސީބަތެއް ވުޖޫދަށް ނެރުއްވުމުގެކުރިން ފޮތެއްގައި (އެބަހީ: އައްލައުޙުލް މަޙްފޫޡުގައި) ލިޔުއްވާފައިވާ ޙާލުގައި މެނުވީ، ބިމަށްވިޔަސް ނުވަތަ ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސު ތަކަށްވިޔަސް އައިސް ނުޖެހެއެވެ. ހަމަކަށަވަރުން، އެކަންތަކަކީ ﷲއަށް ދާދިފަސޭހަ ކަމެކެވެ.","",""],["","","","لكيلا تأسوا على ما فاتكم ولا تفرحوا بما آتاكم والله لا يحب كل مختال فخور","(އެއީ) ތިޔަބައިމީހުންގެ ކިބައިން ފާއިތުވެހިނގައްޖެ ކަމެއްގެ މައްޗަށް ތިޔަބައިމީހުން ހިތާމަ ނުކުޅައުމަށާއި، އަދި އެކަލާނގެ ތިޔަބައިމީހުންނަށް ދެއްވައިފިކަމެއްގެ މައްޗަށް އުފާކޮށް ބޮޑާވެ ނުގަތުމަށްޓަކައެވެ. ކިބުރުވެރިވެ، ފަޚުރުވެރިވާ އެއްވެސް މީހަކުދެކެ ﷲ ލޯބިވެވޮޑިގެނެއް ނުވެތެވެ.","",""],["","","","الذين يبخلون ويأمرون الناس بالبخل ومن يتول فإن الله هو الغني الحميد","އެއުރެންނީ، ދަހިވެތިވާ މީހުންނެވެ. އަދި ދަހިވެތިވުމަށް މީސްތަކުންނަށް އަމުރުކުރާ މީހުންނެވެ. (ﷲގެ މަގަށް) ފުރަގަސްދޭމީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ފުދިވޮޑިގެންވާ، ގިނަގިނައިން ހަމްދު ލިބިވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","لقد أرسلنا رسلنا بالبينات وأنزلنا معهم الكتاب والميزان ليقوم الناس بالقسط وأنزلنا الحديد فيه بأس شديد ومنافع للناس وليعلم الله من ينصره ورسله بالغيب إن الله قوي عزيز","ހަމަކަށަވަރުން، ފާޅުވެގެންވާ ހެކިތަކާއެކު ތިމަންރަސްކަލާނގެ ރަސޫލުން ފޮނުއްވީމެވެ. އަދި އެ ރަސޫލުންނާއެކު، ފޮތާއި، ޢަދުލު އިންޞާފުގެ ތިލަފަތް ބާވައިލެއްވީމެވެ. (އެއީ) މީސްތަކުން ޢަދުލު އިންޞާފު ގާއިމުކުރުމަށްޓަކައެވެ. އަދި ތިމަންރަސްކަލާނގެ ދަގަނޑު ބާވައިލެއްވީމެވެ. އޭގައި ނުހަނު ގަދަފަދަކަމާއި، މީސްތަކުންނަށް މަންފާތަކެއްވެއެވެ. އަދި އެއީ ނުފެންނަތާނގައި ﷲއާއި، އެކަލާނގެ ރަސޫލުންނަށް ނަސްރު ދެނީ ކާކުކަން ﷲ ދެނެވޮޑިގެންވެ، އެކަން އެންގެވުމަށްޓަކައެވެ. ހަމަކަށަވަރުން، ﷲއީ، ބާރުވެރިވަންތަ، ޢަޒީޒުވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ولقد أرسلنا نوحا وإبراهيم وجعلنا في ذريتهما النبوة والكتاب فمنهم مهتد وكثير منهم فاسقون","އަދި ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ނޫޙުގެފާނާއި އިބްރާހީމްގެފާނު ރަސޫލުކަމާއިގެން ފޮނުއްވީމެވެ. އަދި އެ ދެ ރަސޫލުންގެ ދަރިކޮޅުގައި ނަބީކަމާއި (ބާވައިލެއްވި) ފޮތްތައް ލެއްވީމެވެ. ފަހެ، އެއުރެންގެ ތެރެއިން ތެދުމަގު ލިބިގެންވާ މީހުންވެއެވެ. އަދި އެއުރެންގެ ތެރެއިން ގިނަމީހުންނީ، ފާސިގުންނެވެ.","",""],["","","","ثم قفينا على آثارهم برسلنا وقفينا بعيسى ابن مريم وآتيناه الإنجيل وجعلنا في قلوب الذين اتبعوه رأفة ورحمة ورهبانية ابتدعوها ما كتبناها عليهم إلا ابتغاء رضوان الله فما رعوها حق رعايتها فآتينا الذين آمنوا منهم أجرهم وكثير منهم فاسقون","ދެން ތިމަންރަސްކަލާނގެ އެބޭކަލުންނާ ވިދިގެން ފަހަތުން ތިމަންރަސްކަލާނގެ ރަސޫލުން ފޮނުއްވީމެވެ. އަދި މަރިޔަމްގެފާނުގެ ދަރިކަލުން ޢީސާގެފާނު އެބޭކަލުންގެ ފަހުން ފޮނުއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އެކަލޭގެފާނަށް އިންޖީލު ދެއްވީމެވެ. އަދި އެކަލޭގެފާނަށް ތަބާ ވީ މީހުންގެ ހިތްތަކުގައި އޯގާވެރިކަމާއި، ރަޙިމު ލެއްވީމެވެ. އަދި ދުނިޔެ އަޅާފައި (އަޅުކަމުގެ ނަމުގައި) ތިބުމަކީ، އެއުރެން އަމިއްލަޔަށް އުފެއްދި ކަމެކެވެ. އެކަމަކީ، ތިމަންރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް ވާޖިބު ކުރައްވާފައިވާ ކަމެއްނޫނެވެ. އެހެނެއްކަމަކު، އެކަން އެއުރެން ފެށީ، ﷲގެ ރުހިވޮޑިގަތުން އެދިގެންނެވެ. ފަހެ، އެއުރެން ހައްގު ގޮތުގައި އެކަމަށް ރައްކާތެރިވާންވީ ވަރަކަށް ރައްކާތެރިއެއް ނުވެތެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ، އެއުރެންގެ ތެރެއިން އީމާންވި މީހުންނަށް އެއުރެންގެ ދަރުމަ ދެއްވީމެވެ. އަދި އެއުރެންގެ ތެރެއިން ގިނަމީހުންނީ، ފާސިގުންނެވެ.","",""],["","","","يا أيها الذين آمنوا اتقوا الله وآمنوا برسوله يؤتكم كفلين من رحمته ويجعل لكم نورا تمشون به ويغفر لكم والله غفور رحيم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި އެކަލާނގެ ރަސޫލާއަށް އީމާން ވާށެވެ! އޭރުން އެކަލާނގެ ރަހުމަތުން އެކަލާނގެ ތިޔަބައިމީހުންނަށް ދެގުނަ ދެއްވާނެތެވެ. އަދި ތިޔަބައިމީހުންނަށް އޭގެ އަލީގައި މަގު ހިނގާނޭ ނޫރެއް، އެކަލާނގެ ލައްވާނެތެވެ. އަދި އެކަލާނގެ ތިޔަބައިމީހުންނަށް ފާފަފުއްސަވާނެތެވެ. ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","لئلا يعلم أهل الكتاب ألا يقدرون على شيء من فضل الله وأن الفضل بيد الله يؤتيه من يشاء والله ذو الفضل العظيم","އެއީ ﷲގެ ފަޟްލު ވަންތަކަމުގެ ތެރެއިން އެއްވެސްކަމެއްގެ މައްޗަށް އެއުރެންނަށް ކުޅަދާނަވެގެން ނުވާކަން، ފޮތުގެ އަހުލުވެރިން ދެނެގަތުމަށްޓަކައެވެ. އަދި ހަމަކަށަވަރުން، ފަޟްލު ވަންތަކަންވަނީ، ﷲގެ އަތްޕުޅުގައެވެ. އެކަލާނގެ އިރާދަކުރައްވާ އަޅަކަށް އެކަން ދެއްވަތެވެ. ﷲއީ، ބޮޑުވެގެންވާ ފަޟްލު ވަންތަކަމުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم قد سمع الله قول التي تجادلك في زوجها وتشتكي إلى الله والله يسمع تحاوركما إن الله سميع بصير","ހަމަކަށަވަރުން، އެކަނބުލޭގެ ފިރިމީހާއާމެދު ކަލޭގެފާނާ ޖަދަލުކޮށް، އަދި ﷲގެ ހަޒުރަތަށް ޝާކުވާ ދަންނަވާ ކަނބުލޭގެ ބަސް، ﷲ އައްސަވާވޮޑިގެންފިއެވެ. އަދި ތިޔަ ދެފަރާތުގެ ވާހަކަތައް ﷲ އައްސަވާވޮޑިގަންނަވަތެވެ. ހަމަކަށަވަރުން، ﷲއީ، މޮޅަށް އައްސަވާވޮޑިގެންވާ، މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","الذين يظاهرون منكم من نسائهم ما هن أمهاتهم إن أمهاتهم إلا اللائي ولدنهم وإنهم ليقولون منكرا من القول وزورا وإن الله لعفو غفور","ތިޔަބައިމީހުންކުރެ އަނބިންނަށް ޡުހާރުކުރާމީހުން (ދަންނާށެވެ!) އެކަނބަލުންނަކީ، ތިޔަބައިމީހުންގެ މައިންނެއްނޫނެވެ. އެއުރެންވިހޭ ކަނބަލުން މެނުވީ، އެއުރެންގެ މައިންކަމުގައި ނުވެތެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެން އެ ބުނަނީ މުންކަރު ބަހެކެވެ. އަދި ދޮގެކެވެ. އަދި ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން އަފޫކުރައްވާ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަސްކަލާނގެއެވެ.","",""],["","","","والذين يظاهرون من نسائهم ثم يعودون لما قالوا فتحرير رقبة من قبل أن يتماسا ذلكم توعظون به والله بما تعملون خبير","އަދި އެއުރެންގެ އަނބިންނަށް ޡުހާރު ކޮށް، ދެން އެއުރެން ބުނި ބަސް އަނބުރައި ގެނައުމަށް އެދޭމީހުން، އެކަނބަލުންގައި ބީހުމުގެ ކުރީގައި (އެބަހީ: އެއްދާންކުރުމުގެ ކުރީގައި) އަޅަކު މިނިވަންކުރާހުށިކަމެވެ! އެއީ ތިޔަބައިމީހުންނަށް އެކަމަށް ނަސޭހަތް ދެއްވާގޮތެވެ. އަދި ﷲއީ، ތިޔަބައިމީހުންކުރާ ޢަމަލުތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","فمن لم يجد فصيام شهرين متتابعين من قبل أن يتماسا فمن لم يستطع فإطعام ستين مسكينا ذلك لتؤمنوا بالله ورسوله وتلك حدود الله وللكافرين عذاب أليم","ފަހެ، އަޅަކު މިނިވަންކުރަން ނުލިބުނުމީހާ، އެ ދެމަފިރިން އެއްދާންކުރުމުގެ ކުރީގައި ވިދިވިދެގެން ދެމަސްދުވަހު ރޯދަހިފާހުށިކަމެވެ! ފަހެ، ރޯދަހިފުމަށް ނުކުޅެދިއްޖެމީހާ ފަސްދޮޅަސް މިސްކީނުންނަށް ކާންދޭހުށިކަމެވެ! އެއީ ތިޔަބައިމީހުން ﷲއާއި، އެކަލާނގެ ރަސޫލާއަށް އީމާން ވުމަށްޓަކައެވެ. އަދި އެއީ ﷲ ކަނޑައަޅުއްވާފައިވާ އިންތަކެވެ. އަދި ކާފިރުންނަށް ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["","","","إن الذين يحادون الله ورسوله كبتوا كما كبت الذين من قبلهم وقد أنزلنا آيات بينات وللكافرين عذاب مهين","ހަމަކަށަވަރުން، ﷲއާއި، އެކަލާނގެ ރަސޫލާއަށް ދެކޮޅުވެރިވާ މީހުން (ދަންނާށެވެ!) އެއުރެންގެކުރިން އުޅުނު (އެފަދަ) މީހުން ނިކަމެތިކޮށްލެއްވި ފަދައިން، އެއުރެން ނިކަމެތިކޮށްލައްވާ ހުށްޓެވެ. އަދި ހަމަކަށަވަރުން، ބަޔާންވެގެންވާ އާޔަތްތައް ތިމަންރަސްކަލާނގެ ބާވައިލެއްވީމެވެ. އަދި ކާފިރުންނަށް ހުރީ، އިހާނަތްތެރިކަންދެނިވި އަޒާބެވެ.","",""],["","","","يوم يبعثهم الله جميعا فينبئهم بما عملوا أحصاه الله ونسوه والله على كل شيء شهيد","އެއީ ﷲ، އެއުރެން އެންމެން މަހުޝަރަށް ފޮނުއްވާ ދުވަހެވެ. ފަހެ، އެއުރެން ކޮށްއުޅުނު ޢަމަލުތަކުގެ ވާހަކައިން އެކަލާނގެ އެއުރެންނަށް ޚަބަރު އަންގަވާނެތެވެ. ﷲ އެކަންތައްތައް ހިމަނުއްވައި ލިޔުއްވިއެވެ. އަދި އެއުރެން އެކަންތައްތައް ހަނދާން ނައްތައިލޫއެވެ. އަދި ﷲއީ ކޮންމެކަމެއްގެ މައްޗަށް ހެކިވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ألم تر أن الله يعلم ما في السماوات وما في الأرض ما يكون من نجوى ثلاثة إلا هو رابعهم ولا خمسة إلا هو سادسهم ولا أدنى من ذلك ولا أكثر إلا هو معهم أين ما كانوا ثم ينبئهم بما عملوا يوم القيامة إن الله بكل شيء عليم","އުޑުތަކާއި، ބިމުގައިވާހާ ތަކެއްޗާއި، ވާހާކަމެއް ﷲ ދެނެވޮޑިގެންވާކަން ކަލޭގެފާނު ދެނެވަޑައިނުގަންނަވަމުތޯއެވެ؟ ތިންމީހަކު ސިއްރު ސައްލާއެއް ކުރާހިނދު، އެއުރެންގެ ހަތަރުވަނަޔަށް އެކަލާނގެ ވޮޑިގެންނުވާ އެއްވެސް ސައްލާއެއް ނުވެތެވެ. އަދި ފަސްމީހަކު ސައްލާ ކުރާހިނދު، ހަވަނަޔަށް އެކަލާނގެ ވޮޑިގެންނުވާ އެއްވެސް ސައްލާއެއް ނުވެތެވެ. އަދި އެއަށްވުރެ މަދު، ނުވަތަ ގިނަ އަދަދަކަށް ކޮންމެ ތަނެއްގައި އެއުރެންވިޔަސް، އެއުރެންނާއެކު ﷲ ވޮޑިގެންނުވާ ތަނެއްނުވެއެވެ. ދެން އެއުރެން ކޮށްއުޅުނު ޢަމަލުތަކުގެ ވާހަކައިން ގިޔާމަތް ދުވަހުން އެއުރެންނަށް އެކަލާނގެ ޚަބަރު އަންގަވާނެތެވެ. ހަމަކަށަވަރުން، ﷲއީ، ކޮންމެކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ألم تر إلى الذين نهوا عن النجوى ثم يعودون لما نهوا عنه ويتناجون بالإثم والعدوان ومعصيت الرسول وإذا جاءوك حيوك بما لم يحيك به الله ويقولون في أنفسهم لولا يعذبنا الله بما نقول حسبهم جهنم يصلونها فبئس المصير","ސިއްރު ސައްލާކޮށް އުޅުން އެއުރެންނަށް ނަހީކުރައްވާފައިވާ މީހުން ކަލޭގެފާނު ދެކެވަޑައިނުގަންނަވަމުތޯއެވެ؟ ދެން އެއުރެންނަށް ނަހީކުރެއްވި ކަންތައް ކުރުމަށް އެއުރެން އެނބުރި އާދެއެވެ. އަދި ފާފަވެރިކަމާއި، އަދާވަތް ތެރިކަމާއި، ރަސޫލާއަށް ނުކިޔަމަންތެރިވުމަށް އެއުރެން ސިއްރު ސައްލާ ކުރެތެވެ. އަދި އެއުރެން ކަލޭގެފާނުގެ އަރިހަށް އަންނަހިނދު، ކަލޭގެފާނަށް ﷲ ސަލާމް ވަހީ ނުކުރައްވާ ބަހަކުން އެއުރެން ކަލޭގެފާނަށް ސަލާމް ދަންނަވަތެވެ. އަދި އެއުރެންގެ އަމިއްލަ ނަފްސުތަކަށް އެއުރެން ބުނެތެވެ. ތިމަންމެން މިކިޔާ އެއްޗަކަށްޓަކައި ﷲ ތިމަންމެންނަށް އަޒާބު ނުދެއްވަނީ ކީއްވެގެންހެއްޔެވެ؟ ނަރަކަ އެއުރެންނަށް ފުދެއެވެ. އެތަނަށް އެއުރެން ވަންނާނެތެވެ. ފަހެ، އެއީ ހާދަހާ ނުބައިވެގެންވާ ނިމިދިޔުމެކެވެ.","",""],["","","","يا أيها الذين آمنوا إذا تناجيتم فلا تتناجوا بالإثم والعدوان ومعصيت الرسول وتناجوا بالبر والتقوى واتقوا الله الذي إليه تحشرون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ސައްލާއެއް ކުރާހިނދު ފަހެ، ފާފަވެރިކަމާއި، އަދާވަތް ތެރިކަމާއި، ރަސޫލާއަށް ނުކިޔަމަންތެރިވުމަށް ތިޔަބައިމީހުން ސައްލާނުކުރާ ހުށިކަމެވެ! އަދި ހެޔޮކަންތައް ކުރުމާއި، ތަގުވާވެރިވުމަށް ތިޔަބައިމީހުން ސައްލާކުރާށެވެ! އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! ތިޔަބައިމީހުން މަހުޝަރުކުރައްވާހުށީ، ހަމައެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","إنما النجوى من الشيطان ليحزن الذين آمنوا وليس بضارهم شيئا إلا بإذن الله وعلى الله فليتوكل المؤمنون","އީމާންވި މީހުންނަށް ހިތާމަ ދިނުމަށްޓަކައި ސިއްރު ސައްލާކޮށް އުޅުމަކީ ޝައިތާނާގެ ކިބައިން ވާކަމެއްކަން ކަށަވަރެވެ. އަދި ﷲގެ އިޒުނަ ފުޅާލައިގެން މެނުވީ، އެ ޝައިތާނާއަކަށް އެއްވެސްކަމަކުން އެއުރެންނަކަށް ގެއްލުމެއް ނުދެވޭނެތެވެ. ފަހެ، މުއުމިނު ތަކުން ހަމައެކަނި ﷲއަށް ވަކީލުކުރާހުށިކަމެވެ.","",""],["","","","يا أيها الذين آمنوا إذا قيل لكم تفسحوا في المجالس فافسحوا يفسح الله لكم وإذا قيل انشزوا فانشزوا يرفع الله الذين آمنوا منكم والذين أوتوا العلم درجات والله بما تعملون خبير","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! މަޖްލިސް ތަކުގައި ތަންދިނުމަށް ތިޔަބައިމީހުންނަށް ބުނެފިނަމަ، ފަހެ، ތިޔަބައިމީހުން ތަންދޭހުށިކަމެވެ! އޭރުން ﷲ ތިޔަބައިމީހުންނަށް ތަނަވަސްކަން ދެއްވާނެތެވެ. އަދި ތިޔަބައިމީހުންގެ ގާތުގައި ތެދުވާށޭ ބުނެފިނަމަ، ފަހެ، ތިޔަބައިމީހުން (މަޖްލިސްން) ތެދުވާހުށިކަމެވެ! ތިޔަބައިމީހުންގެ ތެރެއިން އީމާންވި މީހުންނާއި، އިލްމު ލިބިގެންވާމީހުން ﷲ ދަރަޖަތަކަކަށް އުފުއްލަވާނެތެވެ. ﷲއީ، ތިޔަބައިމީހުންކުރާ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","يا أيها الذين آمنوا إذا ناجيتم الرسول فقدموا بين يدي نجواكم صدقة ذلك خير لكم وأطهر فإن لم تجدوا فإن الله غفور رحيم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ރަސޫލާއަށް މުނާޖާއެއް ދަންނަވާނަމަ، ތިޔަބައިމީހުން މުނާޖާ ދެންނެވުމުގެ ކުރީގައި (ފަގީރުންނަށް) ސަދަގާތެއް ކުރިމަތިކުރާހުށިކަމެވެ! އެގޮތް ތިޔަބައިމީހުންނަށް ހެޔޮކަންބޮޑެވެ. އަދި ތާހިރު ކަންބޮޑުމެއެވެ. ފަހެ، ތިޔަބައިމީހުންނަށް ސަދަގާތެއް ކުރާނޭ އެއްޗެއް ނުލިބުނުނަމަ، ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","أأشفقتم أن تقدموا بين يدي نجواكم صدقات فإذ لم تفعلوا وتاب الله عليكم فأقيموا الصلاة وآتوا الزكاة وأطيعوا الله ورسوله والله خبير بما تعملون","ތިޔަބައިމީހުން ރަސޫލާއަށް މުނާޖާއެއް ދެންނެވުމުގެކުރިން ސަދަގާތެއް ކުރިމަތިކުރުމަށް ތިޔަބައިމީހުން ބިރުގަތީހެއްޔެވެ؟ ފަހެ، ތިޔަބައިމީހުންނަށް އެކަންތައް ނުކުރެވުނުހިނދު، އަދި ﷲ ތިޔަބައިމީހުންގެ މައްޗަށް ތައުބާ ލައްވައިފިހިނދު، ފަހެ، ތިޔަބައިމީހުން ނަމާދު ގާއިމުކުރާށެވެ! އަދި ޒަކާތް ދޭށެވެ! އަދި ﷲއާއި، އެކަލާނގެ ރަސޫލާއަށް ތިޔަބައިމީހުން ކިޔަމަންވާށެވެ! ﷲއީ، ތިޔަބައިމީހުން ކުރާކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ألم تر إلى الذين تولوا قوما غضب الله عليهم ما هم منكم ولا منهم ويحلفون على الكذب وهم يعلمون","ﷲ، އެއުރެންގެ މައްޗަށް ކޯފާލައްވާފައިވާ ބަޔަކު އެކުވެރި ރަހުމަތް ތެރިން ކަމުގައި ހެދިމީހުންނަށް ކަލޭގެފާނު ނުބައްލަވަމުތޯއެވެ؟ އެއީ ތިޔަބައިމީހުންގެ ތެރެއިންވާ ބަޔެއްނޫނެވެ. އަދި އެއުރެންގެ ތެރެއިންވެސް ހިމެނޭ ބަޔެއްނޫނެވެ. އަދި އެއުރެން ދެނެދެނެތިބެ، ދޮގުގެ މައްޗަށް ހުވާކުރެތެވެ.","",""],["","","","أعد الله لهم عذابا شديدا إنهم ساء ما كانوا يعملون","ﷲ، އެއުރެންނަށްޓަކައި ގަދަވެގެންވާ އަޒާބެއް ތައްޔާރުކުރެއްވިއެވެ. ހަމަކަށަވަރުން، އެއުރެން ކޮށްއުޅުނު ކަންތަކުގެ ނުބައިކަމާއެވެ!","",""],["","","","اتخذوا أيمانهم جنة فصدوا عن سبيل الله فلهم عذاب مهين","އެއުރެންގެ ހުވާތަކަކީ އައްޑަނަތަކެއްކަމުގައި އެއުރެން ހެދޫއެވެ. ފަހެ، އެއުރެން ﷲގެ މަގުން (މީސްތަކުން) އެއްކިބާކުރޫއެވެ. ފަހެ، އެއުރެންނަށް އިހާނަތްތެރިކަންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["","","","لن تغني عنهم أموالهم ولا أولادهم من الله شيئا أولئك أصحاب النار هم فيها خالدون","އެއުރެންގެ މުދަލެއްވެސް، އަދި އެއުރެންގެ ދަރިންނެއްވެސް ﷲގެ ހަޒުރަތުން އެއްވެސްކަމެއް އެއުރެންނަކަށް ފުއްދައެއް ނުދޭނެތެވެ. އެއުރެންނީ، ނަރަކައިގެ އަހުލުވެރިންނެވެ. އެއުރެން އެތާނގައި ދެމިތިބޭނެތެވެ.","",""],["","","","يوم يبعثهم الله جميعا فيحلفون له كما يحلفون لكم ويحسبون أنهم على شيء ألا إنهم هم الكاذبون","ﷲ، އެއުރެން އެންމެން މަހުޝަރަށް ފޮނުއްވާ ދުވަހު، އެއުރެން ތިޔަބައިމީހުންގެ ގާތުގައި (މިއަދު) ހުވާކޮށްއުޅޭ ފަދައިން އެކަލާނގެ ހަޒުރަތު ގައިވެސް އެއުރެން ހުވާކުރާނެތެވެ. އަދި (ފައިދާކުރާނޭ) އެއްޗެއްގެ މަތީގައި އެއުރެންވާކަމަށް އެއުރެން ހީކުރެއެވެ. ދަންނާށެވެ! ހަމަކަށަވަރުން އެއުރެންނީ ހަމަ، ދޮގުވެރިންނެވެ.","",""],["","","","استحوذ عليهم الشيطان فأنساهم ذكر الله أولئك حزب الشيطان ألا إن حزب الشيطان هم الخاسرون","ޝައިތާނު އާވަނީ، އެއުރެންގެ މައްޗަށް ވެރިވެގެންފައެވެ. ފަހެ، އެ ޝައިތާނާ، އެއުރެން ﷲ ހަނދުމަކުރުން ހަނދާންނެތިކޮށްލިއެވެ. އެއުރެންނީ، ޝައިތާނާގެ ޖަމާއަތްގެ މީހުންނެވެ. ދަންނާށެވެ! ހަމަކަށަވަރުން، ޝައިތާނާގެ ޖަމާއަތްގެމީހުންނީ ހަމަ ގެއްލެނިވެގެންވާ މީހުންނެވެ.","",""],["","","","إن الذين يحادون الله ورسوله أولئك في الأذلين","ހަމަކަށަވަރުން، ﷲއާއި، އެކަލާނގެ ރަސޫލާއަށް ދެކޮޅުވެރިވާ މީހުން (ދަންނާށެވެ!) އެއުރެންވަނީ، އެންމެ ދެރަ ނިކަމެތި މީހުންގެ ތެރޭގައެވެ.","",""],["","","","كتب الله لأغلبن أنا ورسلي إن الله قوي عزيز","ﷲ ކަނޑައަޅުއްވައި ލިޔުއްވާފައިވެއެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެއާއި، ތިމަންރަސްކަލާނގެ ރަސޫލުން (އެއުރެންގެ މައްޗަށް) ގަދަވެގަންނަ ހުށީމުއެވެ. ހަމަކަށަވަރުން، ﷲއީ، ބާރުވެރިވަންތަ، ޢަޒީޒުވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","لا تجد قوما يؤمنون بالله واليوم الآخر يوادون من حاد الله ورسوله ولو كانوا آباءهم أو أبناءهم أو إخوانهم أو عشيرتهم أولئك كتب في قلوبهم الإيمان وأيدهم بروح منه ويدخلهم جنات تجري من تحتها الأنهار خالدين فيها رضي الله عنهم ورضوا عنه أولئك حزب الله ألا إن حزب الله هم المفلحون","ﷲއަށާއި، އާޚިރަތް ދުވަހަށް އީމާންވާ މީހުންނީ، ﷲއާއި، އެކަލާނގެ ރަސޫލާއަށް ދެކޮޅުވެރިވާ މީހުންނަށް ލޯބިކުރާ ބަޔަކުކަމުގައިވާތީ ތިބާ ނުދެކޭނޫއެވެ. އެއުރެންނީ، އެއުރެންގެ މައިންބަފައިން ކަމުގައިވިޔަސް، ނުވަތަ ދަރިން ކަމުގައި، ނުވަތަ އަޚުން ކަމުގައި، ނުވަތަ ގާތްތިމާގެ މީހުންކަމުގައި ވިޔަސްމެއެވެ. އެއުރެންނީ، އެއުރެންގެ ހިތްތަކުގައި އެކަލާނގެ އީމާން ކަން ލިޔުއްވި މީހުންނެވެ. އަދި އެކަލާނގެ ހަޒުރަތުން ލިބިފައިވާ ރޫޙަކުން، އެއުރެންނަށް ގަދަކަންދެއްވި މީހުންނެވެ. އަދި އެތާނގެދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކަކަށް އެކަލާނގެ އެއުރެން ވައްދަވާނެތެވެ. އެތާނގައި އެއުރެން ދެމިތިބެނިވި ގޮތުގައެވެ. ﷲއެއުރެންނަށް ރުއްސެވިއެވެ. އަދި އެއުރެން އެކަލާނގެއާމެދު ރުހިގެންވެއެވެ. އެއުރެންނީ ﷲގެ ޖަމާއަތެވެ. ދަންނާށެވެ! ހަމަކަށަވަރުން، ﷲގެ ޖަމާއަތްގެ މީހުންނީ ހަމަ، ދިންނަވާނޭ މީހުންނެވެ.","",""],["","","","بسم الله الرحمن الرحيم سبح لله ما في السماوات وما في الأرض وهو العزيز الحكيم","އުޑުތަކާއި، ބިމުގައިވާހާ ތަކެއްޗެއް ﷲއަށް ތަސްބީހަ ކިޔައިފިއެވެ. އެކަލާނގެއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","هو الذي أخرج الذين كفروا من أهل الكتاب من ديارهم لأول الحشر ما ظننتم أن يخرجوا وظنوا أنهم مانعتهم حصونهم من الله فأتاهم الله من حيث لم يحتسبوا وقذف في قلوبهم الرعب يخربون بيوتهم بأيديهم وأيدي المؤمنين فاعتبروا يا أولي الأبصار","އެކަލާނގެއީ ފޮތުގެ އަހުލުވެރިންކުރެ ކާފިރު ވިމީހުން ފުރަތަމަ ޙަޝްރުގެ ދުވަހު، އެއުރެންގެ ގެދޮރުން ނެރެލެއްވި ރަސްކަލާނގެއެވެ. އެއުރެން ނުކުންނާނޭކަމަކަށް ތިޔަބައިމީހުން ހީއެއް ނުކުރަމުއެވެ. އަދި އެއުރެން ހީކޮށްގެންތިބީ، އެއުރެންގެ ކިއްލާތައް، ﷲގެ ބާރުވެރިކަމުން އެއުރެން ރައްކާތެރިކޮށްދޭނެ ކަމަށެވެ. ފަހެ، އެއުރެންގެ ގާތަށް ﷲގެ ޢިގާބު އައީ، އެއުރެން ހީވެސް ނުކުރާފަދައަކުންނެވެ. އަދި އެކަލާނގެ އެއުރެންގެ ހިތްތަކަށް ބިރުވެރިކަން ވެއްދެވިއެވެ. އެއުރެންގެ އަމިއްލަ އަތްތަކުން އެއުރެންގެ ގެދޮރު ހަލާކު ކުރަމުން ދިޔައޫއެވެ. އަދި މުއުމިނު ތަކުންގެ އަތްތަކުންވެސްމެއެވެ. އޭ ބުއްދީގެ އަހުލުވެރިންނޭވެ! ފަހެ، ތިޔަބައިމީހުން އިބްރަތް ލިބިގަންނާށެވެ.","",""],["","","","ولولا أن كتب الله عليهم الجلاء لعذبهم في الدنيا ولهم في الآخرة عذاب النار","ރަށުން ބޭރުކޮށްލާފައިވާ ބަޔަކުކަމުގައިވުމަށް، ﷲއެއުރެންގެ މައްޗަށް ލިޔުއްވާފައިނުވާނަމަ، ހަމަކަށަވަރުން، އެއުރެންނަށް މިދުނިޔޭގައި އަޒާބު ދެއްވައިފީހެވެ. އަދި އާޚިރަތުގައި ނަރަކައިގެ އަޒާބެއުރެންނަށް ހުށްޓެވެ.","",""],["","","","ذلك بأنهم شاقوا الله ورسوله ومن يشاق الله فإن الله شديد العقاب","އެއީ އެއުރެން ﷲއާއި، އެކަލާނގެ ރަސޫލާއަށް ދެކޮޅުވެރިވީ ކަމަށްޓަކައެވެ. އަދި ﷲއަށް ދެކޮޅުވެރިވާ މީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، އުގޫބާތް ގަދަފަދަވެގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ما قطعتم من لينة أو تركتموها قائمة على أصولها فبإذن الله وليخزي الفاسقين","ތިޔަބައިމީހުން ކަނޑައިލި ކޮންމެ ކަދުރުރުކަކާއި، ނުވަތަ ނުކަނޑައި އޭގެ ބުޑާއެކު ކޮޅަށްހުރުމަށް ދޫކޮށްލި ކޮންމެ ކަދުރުރުކެއް (އެ ކަނޑައިލީ ނުވަތަ ނުކަނޑައި ދޫކޮށްލީ) ފަހެ، ﷲގެ އިޒުނަ ފުޅަށެވެ. އަދި ފާސިގުވި މީހުން ދެރަކޮށް، ނިކަމެތި ކޮށްލުމަށްޓަކައެވެ.","",""],["","","","وما أفاء الله على رسوله منهم فما أوجفتم عليه من خيل ولا ركاب ولكن الله يسلط رسله على من يشاء والله على كل شيء قدير","އަދި އެއުރެންގެ ކިބައިން ﷲ، އެކަލާނގެ ރަސޫލާއަށް ފައިއުގެ ގޮތުގައި ދެއްވައިފި މުދަލަކާމެދު (ދަންނާށެވެ!) ފަހެ، ތިޔަބައިމީހުން އެ މުދާ އަތުލުމަށްޓަކައި، އަހެއްވެސް، ޖަމަލެއްވެސް ދުއްވާފައެއް ނުވެއެވެ. އެހެނެއްކަމަކު ﷲ، އެކަލާނގެ އިރާދަކުރައްވާ ބަޔެއްގެ މައްޗަށް އެކަލާނގެ ރަސޫލުން ބާރުވެރިކުރައްވަތެވެ. އަދި ﷲއީ، ކޮންމެ ކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ما أفاء الله على رسوله من أهل القرى فلله وللرسول ولذي القربى واليتامى والمساكين وابن السبيل كي لا يكون دولة بين الأغنياء منكم وما آتاكم الرسول فخذوه وما نهاكم عنه فانتهوا واتقوا الله إن الله شديد العقاب","ރަށްރަށުގެ އަހުލުވެރިންގެ ކިބައިން، ﷲ، އެކަލާނގެ ރަސޫލާއަށް ފައިއު މުދަލުގެ ގޮތުގައި ލިބިދެއްވައިފި އެއްޗަކާމެދު (ދަންނާށެވެ!) ފަހެ، އެ ތަކެއްޗަކީ، ﷲއަށާއި، ރަސޫލާއަށާއި، ގާތްތިމާގެ މީހުންނަށާއި، ޔަތީމުންނަށާއި، މިސްކީނުންނަށާއި، ދަތުރުވެރިންނަށް ހާއްސަ ވެފައިވާ ތަކެއްޗެވެ. އެއީ އެ މުދާތައް ތިޔަބައިމީހުންކުރެ މުއްސަނދިންގެ މެދުގައި ދައުރު ވޭވެ ހުރިޔަނުދިނުމަށްޓަކައެވެ. އަދި ރަސޫލާ ތިޔަބައިމީހުންނަށް ގެނެސްދެއްވި ކޮންމެ އެއްޗެއްގައި، ފަހެ، ތިޔަބައިމީހުން ހިފާށެވެ! އަދި އެކަލޭގެފާނު ތިޔަބައިމީހުންނަށް ނަހީކުރެއްވި ކޮންމެ ކަމަކުން، ފަހެ، ތިޔަބައިމީހުން ދުރުވެގަންނާށެވެ! އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، އުގޫބާތް ގަދަފަދަވެގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","للفقراء المهاجرين الذين أخرجوا من ديارهم وأموالهم يبتغون فضلا من الله ورضوانا وينصرون الله ورسوله أولئك هم الصادقون","އެއުރެންގެ ގެދޮރުންނާއި، އެއުރެންގެ މުދަލުން ނެރެލާފައިވާ ފަގީރު މުހާޖިރުންނަށް (އެ ފައިއު މުދަލުގައި) ހައްގެއްވެއެވެ. އެއުރެންނީ ﷲގެ ހަޒުރަތުން ފަޟްލު ވަންތަވެރިކަމާއި، ރުހިވޮޑިގަތުން އެދޭ މީހުންނެވެ. އަދި ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް ނަސްރު ދޭ މީހުންނެވެ. އެއުރެންނީ ހަމަ ތެދުވެރިންނެވެ.","",""],["","","","والذين تبوءوا الدار والإيمان من قبلهم يحبون من هاجر إليهم ولا يجدون في صدورهم حاجة مما أوتوا ويؤثرون على أنفسهم ولو كان بهم خصاصة ومن يوق شح نفسه فأولئك هم المفلحون","އަދި އެއުރެންގެ ކުރީގައި، އަލްމަދީނާގައި ވަޒަންވެރިވެ، އީމާންކަމުގައި ގާއިމު ވެތިބި އަންޞާރުން، އެއުރެންގެ ގާތަށް ހިޖުރަކުރި މުހާޖިރު ންދެކެ ލޯބިވެތެވެ. އަދި އެއުރެންނަށް (އެބަހީ: މުހާޖިރުންނަށް) ދެއްވި އެއްވެސް އެއްޗަކަށް އެއްވެސް ބޭނުމެއް (ނުވަތަ ދަހިވެތި ކަމެއް) އެއުރެން (އެބަހީ: އަންޞާރުން) ގެ ހިތްތަކުގައި ނުވެއެވެ. އަދި އެއުރެންގެ އަމިއްލަ ނަފްސުތަކުގެ މައްޗަށް، އެއުރެންނަށް އިސްކަންދެތެވެ. އެއުރެންނަށް ބޭނުންތެރިކަން ބޮޑުވެފައި ވީނަމަވެސްމެއެވެ. އެމީހެއްގެ އަމިއްލަ ނަފްސުގެ ދަހިވެތިކަމުން މިންޖުވެއްޖެ މީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ ހަމަ ދިންނަވާނެ މީހުންނެވެ.","",""],["","","","والذين جاءوا من بعدهم يقولون ربنا اغفر لنا ولإخواننا الذين سبقونا بالإيمان ولا تجعل في قلوبنا غلا للذين آمنوا ربنا إنك رءوف رحيم","އަދި އެއުރެންގެ ފަހުން އައި މީހުން ބުނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެންނަށާއި، އަދި އަޅަމެންނަށްވުރެ ކުރިން އީމާންވި، އަޅަމެންގެ އަޚުންނަށް ފާފަފުއްސަވާނދޭވެ! އަދި އީމާންވި މީހުންނަށް އަޅަމެންގެ ހިތްތަކުގައި ހަސަދަވެރިކަމެއް ނުލައްވާނދޭވެ! އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ، ނުހަނު އޯގާވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ألم تر إلى الذين نافقوا يقولون لإخوانهم الذين كفروا من أهل الكتاب لئن أخرجتم لنخرجن معكم ولا نطيع فيكم أحدا أبدا وإن قوتلتم لننصرنكم والله يشهد إنهم لكاذبون","މުނާފިގު ވިމީހުން ކަލޭގެފާނު ދެކެވަޑައިނުގަންނަވަމުތޯއެވެ؟ ފޮތުގެ އަހުލުވެރިންކުރެ ކާފިރު ވެގެންތިބި އެއުރެންގެ އަޚުންނަށް އެއުރެން ބުނެތެވެ. ތިޔަބައިމީހުން (ރަށުން) ނެރެލައިފިނަމަ، ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނާއެކު ތިމަންމެންވެސް ނުކުންނާނަމެވެ. ތިޔަބައިމީހުންނަށް ގެއްލުންދިނުމުގައި ދުވަހަކުވެސް އެއްވެސް މީހަކަށް ތިމަންމެން ކިޔަމަނެއް ނުވާނޫއެވެ. އަދި ތިޔަބައިމީހުންނާ ދެކޮޅަށް ހަނގުރާމަ ކޮށްފިނަމަ، ހަމަކަށަވަރުން، ތިމަންމެން ތިޔަބައިމީހުންނަށް ނަސްރު ދޭހުށީމުއެވެ. ހަމަކަށަވަރުން އެއުރެންނީ، ދޮގުވެރިންކަމަށް ﷲ ހެކިވެވޮޑިގެންވެތެވެ.","",""],["","","","لئن أخرجوا لا يخرجون معهم ولئن قوتلوا لا ينصرونهم ولئن نصروهم ليولن الأدبار ثم لا ينصرون","ހަމަކަށަވަރުން، އެއުރެން ނެރެލައިފިނަމަ، އެއުރެންނާއެކު އެއުރެންނެއް ނުނިކުންނާނެތެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެންނާ ހަނގުރާމަކޮށްފިނަމަ، އެއުރެންނަކަށް އެއުރެން ނަސްރެއްވެސް ނުދޭނެތެވެ. އަދި ހަމަކަށަވަރުން، އެއުރެންނަށް ނަސްރު ދިނުމަށް ނުކުތަސް، އެއުރެން ފުރަގަސްދީ ފިލަންދުވާނެކަން ކަށަވަރެވެ. ދެން އެއުރެންނަކަށް (އެއްވެސް ފަރާތަކުން) ނަސްރެއް ނުލިބޭނެތެވެ.","",""],["","","","لأنتم أشد رهبة في صدورهم من الله ذلك بأنهم قوم لا يفقهون","އެއުރެންގެ ހިތްތަކުގައި ﷲއަށްވުރެން ތިޔަބައިމީހުންދެކެ ގަންނަ ބިރު ބޮޑުކަން ކަށަވަރެވެ. އެއީ އެއުރެންނީ، ނުވިސްނޭ ބަޔަކުކަމުގައިވާ ކަމަށްޓަކައެވެ.","",""],["","","","لا يقاتلونكم جميعا إلا في قرى محصنة أو من وراء جدر بأسهم بينهم شديد تحسبهم جميعا وقلوبهم شتى ذلك بأنهم قوم لا يعقلون","ރައްކާތެރި ކުރައްވާފައިވާ ރަށްތަކެއްގައި ތިބެގެން، ނުވަތަ ފާރުތަކެއްގެ ނިވަލުގައި ތިބެގެން މެނުވީ، އެއުރެން އެންމެން އެކުގައި (ނުކުމެ) ތިޔަބައިމީހުންނަކާ ހަނގުރާމައެއް ނުކުރާނެތެވެ. އެއުރެންގެ މެދުގައި ހިނގާ ހަނގުރާމަ ގަދަފަދަ ވެގެންވެއެވެ. އެއުރެންގެ ހިތްތައް ބައިބައިވެގެންވާ ޙާލު، ތިބާ ހީކުރަނީ، އެއުރެންނީ، އެންމެން އެކަތިގަނޑަކަށްވެފައިވާ ބަޔެއްކަމުގައެވެ. އެއީ، އެއުރެންނީ، ނުވިސްނޭ ބަޔަކުކަމުގައިވާ ކަމަށްޓަކައެވެ.","",""],["","","","كمثل الذين من قبلهم قريبا ذاقوا وبال أمرهم ولهم عذاب أليم","އެއުރެންނަށްވުރެ ތަންކޮޅެއްކުރިން އުޅުނު މީހުން ފަދައިންނެވެ. އެއުރެންގެ ނުބައި ޢަމަލުގެ ރަހަ، އެއުރެންނަށް ލިބުނެވެ. އަދި އެއުރެންނަށް (އާޚިރަތުގައި) ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["","","","كمثل الشيطان إذ قال للإنسان اكفر فلما كفر قال إني بريء منك إني أخاف الله رب العالمين","ޝައިތާނާގެ މިސާލު ގައެވެ. އޭނާ އިންސާނާޔަށް ކާފިރު ވާށޭ ބުނިހިނދެވެ. ފަހެ، އެ އިންސާނާ ކާފިރު ވީހިނދު އެ ޝައިތާނާ ބުންޏެވެ. ހަމަކަށަވަރުން، ތިމަންވަނީ، ތިބާގެ ކިބައިން ބަރީއަވެގެންނެވެ. ހަމަކަށަވަރުން، އާލަމްތަކުގެ ވެރި ﷲއަށް ތިމަން ބިރުގަނެތެވެ.","",""],["","","","فكان عاقبتهما أنهما في النار خالدين فيها وذلك جزاء الظالمين","އެ ދެމީހުންގެ ނިމުމެއް ކަމުގައިވާނީ، އެ ދެމީހުން ނަރަކަޔަށް ވަނުމެވެ. އެތާނގައި، އެއުރެން ދެމިތިބެނިވި ގޮތުގައެވެ. އަދި އެއީ އަނިޔާވެރިންގެ ޖަޒާއެވެ.","",""],["","","","يا أيها الذين آمنوا اتقوا الله ولتنظر نفس ما قدمت لغد واتقوا الله إن الله خبير بما تعملون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ކޮންމެ ނަފްސެއްމެ، މާދަމައަށްޓަކައި އިސްކޮށްފައިވާ ޢަމަލެއް ބަލައިފާހުށިކަމެވެ! އަދި ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ތިޔަބައިމީހުންކުރާ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ولا تكونوا كالذين نسوا الله فأنساهم أنفسهم أولئك هم الفاسقون","އަދި ﷲ ހަނދުމަ ނައްތައިލި މީހުން ފަދައިން ތިޔަބައިމީހުން ނުވާށެވެ! ފަހެ، އެކަލާނގެ އެއުރެންގެ އަމިއްލަ ނަފްސުތައް ހަނދުމަނެތިކޮށްލެއްވިއެވެ. އެއުރެންނީ، ހަމަ ފާސިގުންނެވެ.","",""],["","","","لا يستوي أصحاب النار وأصحاب الجنة أصحاب الجنة هم الفائزون","ނަރަކައިގެ އަހުލުވެރިންނާއި، ސުވަރުގޭގެ އަހުލުވެރިން ހަމަހަމައެއް ނުވާނެތެވެ. ސުވަރުގޭގެ އަހުލުވެރިންނީ، ހަމަ ނަސީބު ލިބިގެންވާ މީހުންނެވެ.","",""],["","","","لو أنزلنا هذا القرآن على جبل لرأيته خاشعا متصدعا من خشية الله وتلك الأمثال نضربها للناس لعلهم يتفكرون","ތިމަންރަސްކަލާނގެ ފަރުބަދައެއްގެ މައްޗަށް މި ގުރްއާން ބާވައިލެއްވިނަމަ، ހަމަކަށަވަރުން، އެ ފަރުބަދައެއް ﷲއަށް ބިރުވެތިވުމުގެ ސަބަބުން ކުނޑިކުނޑިވެގެން ތިރިވާތީ ތިބާއަށް ފެނުނީހެވެ. އަދި އެ މިސާލުތައް މީސްތަކުންނަށް ތިމަންރަސްކަލާނގެ ޖައްސަވަނީ، އެއުރެން ފިކުރުކުރުމަށްޓަކައެވެ.","",""],["","","","هو الله الذي لا إله إلا هو عالم الغيب والشهادة هو الرحمن الرحيم","އެކަލާނގެއީ، ﷲއެވެ. އެކަލާނގެއީ، އެކަލާނގެ ފިޔަވައި ހައްގު ވެގެން އަޅުކަމެއްވެވޭ އިލާހަކު ނުވާ ރަސްކަލާނގެއެވެ. ނުފެންނަ ކަންތަކާއި، ފެންނަ ކަންތައް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އެކަލާނގެއީ، ރަޙްމާންވަންތަ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","هو الله الذي لا إله إلا هو الملك القدوس السلام المؤمن المهيمن العزيز الجبار المتكبر سبحان الله عما يشركون","އެކަލާނގެއީ، ﷲއެވެ. އެކަލާނގެއީ، އެކަލާނގެ ފިޔަވައި ހައްގު ވެގެން އަޅުކަމެއްވެވޭ އިލާހަކު ނުވާ ރަސްކަލާނގެއެވެ. ރަސްވަންތަ ރަސްކަލާނގެއެވެ. ތާހިރުވަންތަ ރަސްކަލާނގެއެވެ. ހުރިހާ އުނިކަމަކުން ހުސްދުރުވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. އަމާން ކަން ދެއްވާ ރަސްކަލާނގެއެވެ. ހުރިހާ އެއްޗެއް ރައްކާތެރިކުރައްވައި ބަލަހައްޓަވާ ރަސްކަލާނގެއެވެ. ޢަޒީޒުވަންތަ ރަސްކަލާނގެއެވެ. ޖައްބާރުވަންތަ ރަސްކަލާނގެއެވެ. ޢަޡަމަތް ތެރިވަންތަ ރަސްކަލާނގެއެވެ. އެއުރެން ޝަރީކުކުރާ ތަކެތިން ﷲ ހުސްތާހިރުވަންތަވެވޮޑިގެންވެތެވެ.","",""],["","","","هو الله الخالق البارئ المصور له الأسماء الحسنى يسبح له ما في السماوات والأرض وهو العزيز الحكيم","އެކަލާނގެއީ، ﷲއެވެ. ހުރިހާ އެއްޗެއް ހައްދަވާ ރަސްކަލާނގެއެވެ. ހުރިހާ އެއްޗެއް އުފައްދަވާ ރަސްކަލާނގެއެވެ. ޞޫރަކުރައްވާ ރަސްކަލާނގެއެވެ. އެންމެހާ ރިވެތި ނަންފުޅުތައް މިލްކުވެގެންވަނީ، އެކަލާނގެއަށެވެ. އުޑުތަކާއި، ބިމުގައިވާހާ ތަކެއްޗެއް އެކަލާނގެއަށް ތަސްބީހަ ދަންނަވަތެވެ. އަދި އެކަލާނގެއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم يا أيها الذين آمنوا لا تتخذوا عدوي وعدوكم أولياء تلقون إليهم بالمودة وقد كفروا بما جاءكم من الحق يخرجون الرسول وإياكم أن تؤمنوا بالله ربكم إن كنتم خرجتم جهادا في سبيلي وابتغاء مرضاتي تسرون إليهم بالمودة وأنا أعلم بما أخفيتم وما أعلنتم ومن يفعله منكم فقد ضل سواء السبيل","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިމަންރަސްކަލާނގެ އަދުއްވްނާއި، އަދި ތިޔަބައިމީހުންގެ އަދުއްވުންނަކީ، އެހީތެރިންކަމުގައި ތިޔަބައިމީހުން ނުހިފާށެވެ! ތިޔަބައިމީހުން، އެއުރެންނަށް ލޯތްބާއި، އެކުވެރިކަން ހުށަހަޅަމުއެވެ. އަދި ތިޔަބައިމީހުންގެ ގާތަށްއައި ހައްގު ދީނަށް އެއުރެންވަނީ ކާފިރު ވެފައެވެ. ތިޔަބައިމީހުންގެ ވެރި ﷲއަށް ތިޔަބައިމީހުން އީމާންވާ ކަމަށްޓަކައި، އެއުރެން ރަސޫލާއާއި، ތިޔަބައިމީހުން ރަށުން ބޭރުކޮށްލައެވެ. ތިމަންރަސްކަލާނގެ މަގުގައި ޖިހާދުކުރުމަށާއި، އަދި ތިމަންރަސްކަލާނގެ ރުއްސެވުން އަދައިގެން، ތިޔަބައިމީހުން ނުކުތް ކަމުގައިވާނަމަ (ތިޔަބައިމީހުން ތިމަންރަސްކަލާނގެ އަދުއްވުންނަށް ރަހުމަތް ތެރިކަން ނުބަހައްޓާށެވެ!) ތިޔަބައިމީހުން އެއުރެންނަށް ލޯތްބާއެކު ސިއްރު ވާހަކަ ދައްކަމުއެވެ. ތިޔަބައިމީހުން ފޮރުވާކަންތަކާއި، އަދި ތިޔަބައިމީހުން ފާޅުކުރާ ކަންތައް ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގަތުން ބޮޑެވެ. ތިޔަބައިމީހުންކުރެ އެފަދަ ޢަމަލުކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހަކަށް ސީދާވެގެންވާ މަގު ގެއްލިއްޖެކަން ކަށަވަރެވެ.","",""],["","","","إن يثقفوكم يكونوا لكم أعداء ويبسطوا إليكم أيديهم وألسنتهم بالسوء وودوا لو تكفرون","އެއުރެން ތިޔަބައިމީހުންގެ މައްޗަށް ގަދަވެއްޖެނަމަ، އެއުރެންވާހުށީ ތިޔަބައިމީހުންނަށްހުރި އަދުއްވުން ކަމުގައެވެ. އަދި އެއުރެންގެ އަތްތަކާއި، ދޫތައް ނުބައިގޮތުގައި ތިޔަބައިމީހުންގެ މައްޗަށް ފަތުރައިލާނެތެވެ. އަދި ތިޔަބައިމީހުން ކާފިރު ވާނެ ނަމައޭ ހިތައި، އެއުރެން އެކަމަށް އެދޭނެތެވެ.","",""],["","","","لن تنفعكم أرحامكم ولا أولادكم يوم القيامة يفصل بينكم والله بما تعملون بصير","ތިޔަބައިމީހުންގެ ގާތްތިމާގެ މީހުންނާއި، ތިޔަބައިމީހުންގެ ދަރިން، ގިޔާމަތް ދުވަހުން ތިޔަބައިމީހުންނަކަށް މަންފާއެއް ނުކޮށްދޭނެތެވެ. ތިޔަބައިމީހުންގެ މެދުގައި އެކަލާނގެ (އެދުވަހުން) ނިޔާކުރައްވާނެތެވެ. ﷲއީ، ތިޔަބައިމީހުންކުރާ ކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","قد كانت لكم أسوة حسنة في إبراهيم والذين معه إذ قالوا لقومهم إنا برآء منكم ومما تعبدون من دون الله كفرنا بكم وبدا بيننا وبينكم العداوة والبغضاء أبدا حتى تؤمنوا بالله وحده إلا قول إبراهيم لأبيه لأستغفرن لك وما أملك لك من الله من شيء ربنا عليك توكلنا وإليك أنبنا وإليك المصير","އިބްރާހީމްގެފާނާއި، އަދި އެކަލޭގެފާނުގެ އަރިހުގައިވާ މީހުންގައި ތިޔަބައިމީހުންނަށް ރިވެތިވެގެންވާ ނަމޫނާއެއްވާކަން ކަށަވަރެވެ. (އެއީ) އެއުރެން، އެއުރެންގެ ގައުމަށް ބުނިހިނދެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނާއި، ﷲ ފިޔަވައި ތިޔަބައިމީހުން އަޅުކަންކުރާ ތަކެތިން، ތިމަންމެން ބަރީއަވެގެންވަމުއެވެ. ތިޔަބައިމީހުންގެ ދީނަށް ތިމަންމެން އިންކާރުކުރަމުއެވެ. ތިމަންމެންނާއި، ތިޔަބައިމީހުންނާ ދެމެދުގައި އަދާވަތް ތެރިކަމާއި، ރުޅިވެރިކަންވަނީ އަބަދަށްޓަކައި ފާޅުވެފައެވެ. އެއްކައުވަންތަ ﷲއަށް ތިޔަބައިމީހުން އީމާން ވެއްޖައުމަށް ދާނދެނެވެ. އިބްރާހީމްގެފާނު އެކަލޭގެފާނުގެ ބައްޕައަށް ވިދާޅުވި ބަސްފުޅު މެނުވީއެވެ. ހަމަކަށަވަރުން، ތިބާއަށް ފާފަފުއްސެވުންއެދި ތިމަންކަލޭގެފާނު ދުއާކުރައްވާހުށީމެވެ. (އެހެނެއްކަމަކު) ﷲގެ ހަޒުރަތުން ތިބާއަށްޓަކައި އެއްވެސްކަމެއް ކޮށްދިނުމުގެ ބާރެއް ތިމަންކަލޭގެފާނަކަށް ލިބިގެނެއް ނުވެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ހަމައެކަނި، އިބަރަސްކަލާނގެއަށް އަޅަމެން ވަކީލު ކޮށްފީމުއެވެ. އަދި ހަމައެކަނި، އިބަރަސްކަލާނގެ ހަޒުރަތަށް އަޅަމެން ރުޖޫއަވެ ތައުބާ ވެއްޖައީމުއެވެ. އަދި އެނބުރި ދިޔުންވަނީ، އިބަރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","ربنا لا تجعلنا فتنة للذين كفروا واغفر لنا ربنا إنك أنت العزيز الحكيم","އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ކާފިރުވި މީހުންނަށް ފިތުނައެއް ކަމުގައި އަޅަމެން ނުލައްވާނދޭވެ! އަދި އަޅަމެންނަށް ފާފަފުއްސަވާނދޭވެ! އަޅަމެންގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","لقد كان لكم فيهم أسوة حسنة لمن كان يرجو الله واليوم الآخر ومن يتول فإن الله هو الغني الحميد","އެބޭކަލުންގައި ތިޔަބައިމީހުންނަށް ރިވެތި ނަމޫނާއެއް ވާކަން ކަށަވަރެވެ. ﷲއާއި، އާޚިރަތް ދުވަސް އެދޭކަމުގައިވީ މީހަކަށެވެ. އަދި ފުރަގަސްދީ އެނބުރިގަންނަ މީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ފުދިވޮޑިގެންވާ، ހަމްދު ލިބިވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","عسى الله أن يجعل بينكم وبين الذين عاديتم منهم مودة والله قدير والله غفور رحيم","އެއުރެންކުރެ ތިޔަބައިމީހުން އަދާވަތް ތެރިވި މީހުންނާއި، ތިޔަބައިމީހުންނާ ދެމެދުގައި ﷲ އެކުވެރިކަން ލައްވައިފާށިއެވެ! ﷲއީ، ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ. އަދި ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","لا ينهاكم الله عن الذين لم يقاتلوكم في الدين ولم يخرجوكم من دياركم أن تبروهم وتقسطوا إليهم إن الله يحب المقسطين","ތިޔަބައިމީހުންގެ ދީން އާހުރެ، ތިޔަބައިމީހުންނާ ހަނގުރާމަނުކުރާ، އަދި ތިޔަބައިމީހުންގެ ގޮވަތި ގެދޮރުން ތިޔަބައިމީހުން ބޭރުކޮށްނުލާ މީހުންނަށް ތިޔަބައިމީހުން ހެޔޮކޮށްހިތައި، އަދި އެއުރެންނަށް ޢަދުލުވެރިގޮތުގައި ކަންތައް ކުރުން، ﷲ ތިޔަބައިމީހުންނަކަށް މަނައެއް ނުކުރައްވަތެވެ. ހަމަކަށަވަރުން، ޢަދުލުވެރިންދެކެ ﷲ ލޯބިވެވޮޑިގެންވެތެވެ.","",""],["","","","إنما ينهاكم الله عن الذين قاتلوكم في الدين وأخرجوكم من دياركم وظاهروا على إخراجكم أن تولوهم ومن يتولهم فأولئك هم الظالمون","ﷲ، ތިޔަބައިމީހުންނަށް މަނާކުރައްވާކަން ކަށަވަރީ، ތިޔަބައިމީހުންގެ ދީން އާހުރެ ތިޔަބައިމީހުންނާ ހަނގުރާމަކޮށް، އަދި ތިޔަބައިމީހުންގެ ގޮވަތިގެދޮރުން ތިޔަބައިމީހުން ނެރެލައި، އަދި ތިޔަބައިމީހުން ބޭރުކޮށްލުމަށް ވާގިވެރިވާ މީހުންނާ އެކުވެރިކަން ބެހެއްޓުމެވެ. އެއުރެންނާ އެކުވެރިކަން ބަހައްޓާ މީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ، ހަމަ އަނިޔާވެރިންނެވެ.","",""],["","","","يا أيها الذين آمنوا إذا جاءكم المؤمنات مهاجرات فامتحنوهن الله أعلم بإيمانهن فإن علمتموهن مؤمنات فلا ترجعوهن إلى الكفار لا هن حل لهم ولا هم يحلون لهن وآتوهم ما أنفقوا ولا جناح عليكم أن تنكحوهن إذا آتيتموهن أجورهن ولا تمسكوا بعصم الكوافر واسألوا ما أنفقتم وليسألوا ما أنفقوا ذلكم حكم الله يحكم بينكم والله عليم حكيم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ ގާތަށް މުއުމިނު އަންހެނުން ހިޖުރަ ކޮށްފައި އަންނަހިނދު، ފަހެ، ތިޔަބައިމީހުން އެކަނބަލުން އިމްތިހާނުކުރާށެވެ! އެކަނބަލުންގެ އީމާން ކަން ހުރިގޮތް ﷲ ދެނެވޮޑިގަތުން ބޮޑެވެ. ފަހެ، އެކަނބަލުންނީ، (ހަގީގަތުގައި) މުއުމިނު ންކަން ތިޔަބައިމީހުންނަށް އެނގިއްޖެނަމަ، ފަހެ، ކާފިރު ންގެގާތަށް ތިޔަބައިމީހުން އެކަނބަލުން އަނބުރައި ނުފޮނުވާހުށިކަމެވެ! އެކަނބަލުން އެއުރެންނަށް ހަލާލު ވެގެނެއް ނުވެތެވެ. އަދި އެއުރެންވެސް އެކަނބަލުންނަކަށް ހަލާލު ވެގެނެއް ނުމެވޭމެއެވެ. އަދި އެއުރެން (ކާވެނީގެ ރަނުގެ ގޮތުގައި) ހޭދަކޮށްފައިވާ އެއްޗެއް ތިޔަބައިމީހުން އެއުރެންނަށް ދޭހުށިކަމެވެ! އަދި އެކަނބަލުންގެ ކާވެނީގެ ރަން އެކަނބަލުންނަށް ތިޔަބައިމީހުންދޭނަމަ، ތިޔަބައިމީހުން އެކަނބަލުންނާ ކާވެނި ކުރުމުގައި، ތިޔަބައިމީހުންގެ މައްޗަކަށް ކުށެއް ނެތެވެ. އަދި ތިޔަބައިމީހުން، ކާފިރު އަންހެނުން އަނބިންގެ ގޮތުގައި ނުބައިތިއްބާށެވެ! އަދި ތިޔަބައިމީހުން (އެކަނބަލުންނަށް) ރަނުގެ ގޮތުގައިދިން އެއްޗެއް އަތުލުމަށް ތިޔަބައިމީހުން ސުވާލުކުރާށެވެ! އަދި އެ ކާފިރުން ހޭދަކުރި އެއްޗެއް އަތުލުމަށް އެއުރެންވެސް ސުވާލުކުރާހުށިކަމެވެ! އެއީ ﷲގެ ހުކުމް ފުޅެވެ. އެކަލާނގެ ތިޔަބައިމީހުންގެ މެދުގައި ނިޔާކުރައްވަތެވެ. ﷲއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وإن فاتكم شيء من أزواجكم إلى الكفار فعاقبتم فآتوا الذين ذهبت أزواجهم مثل ما أنفقوا واتقوا الله الذي أنتم به مؤمنون","އަދި ތިޔަބައިމީހުންގެ އަނބިންކުރެ މީހަކު، ތިޔަބައިމީހުން ދޫކޮށް ކާފިރުންގެ ގާތަށް ހިނގައްޖެނަމަ، ދެން ތިޔަބައިމީހުން ހަނގުރާމަކޮށް (ޣަނީމާގެ މުދާ ލިބުމުން) ފަހެ، އެއުރެންގެ ކިބައިން، އެއުރެންގެ އަނބިން ގޮސްފައިވާ މީހުންނަށް، އެއުރެން ރަނުގެ ގޮތުގައި ހޭދަކުރިފަދަ އެއްޗެއް ތިޔަބައިމީހުން (އެ ޣަނީމާ އިން) ދޭށެވެ! އަދި ތިޔަބައިމީހުން އެކަލާނގެއަށް އީމާން ވެގެންވާ (ކަލާނގެ ކަމުގައިވާ) ﷲއަށް ތިޔަބައިމީހުން ތަގުވާވެރިވާށެވެ!","",""],["","","","يا أيها النبي إذا جاءك المؤمنات يبايعنك على أن لا يشركن بالله شيئا ولا يسرقن ولا يزنين ولا يقتلن أولادهن ولا يأتين ببهتان يفترينه بين أيديهن وأرجلهن ولا يعصينك في معروف فبايعهن واستغفر لهن الله إن الله غفور رحيم","އޭ ނަބިއްޔާއެވެ! އީމާން ވެގެންވާ އަންހެނުން ކަލޭގެފާނުގެ އަރިހަށް ބައިޢަތު ހިފުމަށް އަންނަހިނދު، އެކަނބަލުން اللًّه އާ އެއްވެސް އެއްޗެއް ޝަރީކު ނުކުޅައުމަށާއި، އެކަނބަލުން ވައްކަން ނުކުޅައުމަށާއި، އެކަނބަލުން ޒިނޭ ނުކުޅައުމަށާއި، އެކަނބަލުންގެ ދަރިން ނުމެރުމަށާއި، އަދި އެކަނބަލުންގެ އަތްތަކާއި ފައިތަކާ ދެމެދަށް ބުހުތާނު ދޮގު ވާހަކައެއް ހަދައިގެން ނުގެނައުމަށާއި (އެބަހީ: ނަހަލާލު ކުދިން ހަލާލު ކުދިން ކަމުގައި ނުހެދުމަށާއި) އަދި އެއްވެސް ހެޔޮކަމެއްގައި ކަލޭގެފާނަށް އެކަނބަލުން އުރެދިނުގަތުމަށް، ފަހެ، ކަލޭގެފާނު އެކަނބަލުންނާ ބައިޢަތު ހިއްޕަވާށެވެ! އަދި އެކަނބަލުންނަށް ފާފަފުއްސެވުންއެދި ކަލޭގެފާނު ﷲއަށް ދަންނަވާށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","يا أيها الذين آمنوا لا تتولوا قوما غضب الله عليهم قد يئسوا من الآخرة كما يئس الكفار من أصحاب القبور","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! އެބައެއްގެ މައްޗަށް ﷲ ކޯފާލައްވާފައިވާ ބަޔަކާ ތިޔަބައިމީހުން އެކުވެރިވެ ނޫޅޭށެވެ! ހަމަކަށަވަރުން، އެއުރެންވަނީ އާޚިރަތާމެދު މާޔޫސްވެގެންނެވެ. ކަށްވަޅުގެ އަހުލުވެރިންނާމެދު ކާފިރުން މާޔޫސްވީ ފަދައިންނެވެ.","",""],["","","","بسم الله الرحمن الرحيم سبح لله ما في السماوات وما في الأرض وهو العزيز الحكيم","އުޑުތަކާއި، ބިމުގައިވާހާ ތަކެއްޗެއް ﷲއަށް ތަސްބީހަ ކިޔައިފިއެވެ. އަދި އެކަލާނގެއީ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","يا أيها الذين آمنوا لم تقولون ما لا تفعلون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ނުކުރާ ކަންތަކުގެ ވާހަކަ ތިޔަބައިމީހުން ބުނެއުޅެނީ ކީއްވެގެން ހެއްޔެވެ؟","",""],["","","","كبر مقتا عند الله أن تقولوا ما لا تفعلون","ތިޔަބައިމީހުން ނުކުރާ ކަންތަކުގެ ވާހަކަ ބުނުން، ﷲގެ ހަޒުރަތުގައި ނުރުއްސެވުން ބޮޑުވެގެންވެތެވެ.","",""],["","","","إن الله يحب الذين يقاتلون في سبيله صفا كأنهم بنيان مرصوص","ހަމަކަށަވަރުން، ހަރުދަނާ ބިނާއެއް ފަދައިން ސަފުސަފަށް އެތުރިގެންތިބެ، އެކަލާނގެ މަގުގައި ހަނގުރާމަކުރާ މީހުންދެކެ، ﷲ ލޯބިވެވޮޑިގެންވެތެވެ.","",""],["","","","وإذ قال موسى لقومه يا قوم لم تؤذونني وقد تعلمون أني رسول الله إليكم فلما زاغوا أزاغ الله قلوبهم والله لا يهدي القوم الفاسقين","އަދި މޫސާގެފާނު އެކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް ވިދާޅުވިހިނދު (ހަނދުމަކުރާށެވެ!) އޭ އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ތިޔަބައިމީހުން އަހުރެންނަށް އުނދަގޫކުރަނީ ކީއްވެގެން ހެއްޔެވެ؟ ހަމަކަށަވަރުން، އަހުރެންނީ ތިޔަބައިމީހުންގެ ގާތަށް ﷲ ފޮނުއްވި ރަސޫލު އާކަން ތިޔަބައިމީހުން ދެނެތިބި ޙާލު ގައެވެ. ފަހެ، އެއުރެން (ހައްގުން) އެއްކިބާވިހިނދު، ﷲއެއުރެންގެ ހިތްތައް (ތެދުމަގުން) އެއްކިބާ ކުރެއްވިއެވެ. ފާސިގު ވީ މީހުންނަށް ﷲ ތެދުމަގެއް ނުދައްކަވާނެތެވެ.","",""],["","","","وإذ قال عيسى ابن مريم يا بني إسرائيل إني رسول الله إليكم مصدقا لما بين يدي من التوراة ومبشرا برسول يأتي من بعدي اسمه أحمد فلما جاءهم بالبينات قالوا هذا سحر مبين","އަދި މަރިޔަމްގެފާނުގެ ދަރިކަލުން ޢީސާގެފާނު ވިދާޅުވިހިނދު (ހަނދުމަކުރާށެވެ!) އޭ އިސްރާއީލުގެދަރިންނޭވެ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނީ، ތިޔަބައިމީހުންގެ ގާތަށް ﷲ ފޮނުއްވި ރަސޫލާއެވެ. ތިމަންކަލޭގެފާނުގެ ކުރީގައިވާ ތައުރާތުގެ ހުކުމްތައް ތެދުކުރައްވާ ބޭކަލަކު ކަމުގައެވެ. އަދި ތިމަންކަލޭގެފާނަށްފަހު އަޙްމަދެވެ ނަމަކަށް ކިއުނު ރަސޫލަކު ވަޑައިގަންނަވާނޭކަމުގެ އުފާވެރި ޚަބަރު ދެއްވާ ބޭކަލަކު ކަމުގައެވެ. ފަހެ، އެއުރެންގެ ގާތަށް ފާޅުވެގެންވާ ހެކިތަކާއެކު އެކަލޭގެފާނު ވަޑައިގެންނެވިހިނދު އެއުރެން ބުނޫއެވެ. މިއީ ފާޅުވެގެންވާ ޖާދޫއެކެވެ.","",""],["","","","ومن أظلم ممن افترى على الله الكذب وهو يدعى إلى الإسلام والله لا يهدي القوم الظالمين","އެމީހަކަށް އިސްލާމް ދީނަށް ގޮވައިލައްވާ ޙާލު، ﷲއާމެދު ހަދައިގެން ދޮގުބުނި މީހަކަށްވުރެން އަނިޔާވެރިކަންބޮޑީ ކާކުހެއްޔެވެ؟ އަނިޔާވެރި ބަޔަކަށް ﷲ ތެދުމަގެއް ނުދައްކަވަތެވެ.","",""],["","","","يريدون ليطفئوا نور الله بأفواههم والله متم نوره ولو كره الكافرون","އެއުރެން އެދެނީ، ﷲގެ ނޫރުފުޅު (އެބަހީ: އިސްލާމް ދީން) އެއުރެންގެ އަނގަތަކުންފުމެ، ނިއްވައިލުމަށެވެ. އަދި ކާފިރުން ނުރުހުނުކަމުގައިވިޔަސް ﷲ، އެކަލާނގެ ނޫރުފުޅު ފުރިހަމަކުރައްވާހުށްޓެވެ.","",""],["","","","هو الذي أرسل رسوله بالهدى ودين الحق ليظهره على الدين كله ولو كره المشركون","އެކަލާނގެއީ، ތެދުމަގާއި، ހައްގު ދީނާއިގެން އެކަލާނގެ ރަސޫލާ ފޮނުއްވި ރަސްކަލާނގެއެވެ. އެއީ އެންމެހާ ދީންތަކުގެ މައްޗަށް އެ ދީން މަތިވެރި ކުރެއްވުމަށެވެ. މުޝްރިކުން ނުރުހުނުކަމުގައި ވިޔަސްމެއެވެ.","",""],["","","","يا أيها الذين آمنوا هل أدلكم على تجارة تنجيكم من عذاب أليم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ވޭންދެނިވި އަޒާބަކުން ތިޔަބައިމީހުން މިންޖުކޮށްދޭނޭ ވިޔަފާރިއެއް ތިޔަބައިމީހުންނަށް ތިމަންރަސްކަލާނގެ ދައްކަވަން ހެއްޔެވެ؟","",""],["","","","تؤمنون بالله ورسوله وتجاهدون في سبيل الله بأموالكم وأنفسكم ذلكم خير لكم إن كنتم تعلمون","(އެއީ) ތިޔަބައިމީހުން ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް އީމާން ވުމެވެ. އަދި ތިޔަބައިމީހުންގެ މުދާތަކުންނާއި، ތިޔަބައިމީހުންގެ ނަފްސު ތަކުން ﷲގެ މަގުގައި ތިޔަބައިމީހުން ޖިހާދުކުރުމެވެ. ތިޔަބައިމީހުން ދަންނަނަމަ، އެގޮތް ތިޔަބައިމީހުންނަށް މާ ހެޔޮކަން ބޮޑެވެ.","",""],["","","","يغفر لكم ذنوبكم ويدخلكم جنات تجري من تحتها الأنهار ومساكن طيبة في جنات عدن ذلك الفوز العظيم","އޭރުން އެކަލާނގެ ތިޔަބައިމީހުންނަށް ތިޔަބައިމީހުންގެ ފާފަތައް ފުއްސަވާނެތެވެ. އަދި އެތާނގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކަށް އެކަލާނގެ ތިޔަބައިމީހުން ވައްދަވާނެތެވެ. އަދި ޢަދަނެވެ ކިއުނު ސުވަރުގެތަކުގައިވާ ރަނގަޅު ގޮވަތިގެދޮރުގައި ތިޔަބައިމީހުން ވަޒަންވެރި ކުރައްވާނެތެވެ. ބޮޑުވެގެންވާ ނަސީބު ލިބުމަކީ އެއީއެވެ.","",""],["","","","وأخرى تحبونها نصر من الله وفتح قريب وبشر المؤمنين","އަދި ތިޔަބައިމީހުން އެއަށް ލޯބިވާނޭ އެހެން ނިއުމަތެއް އެކަލާނގެ ދެއްވާނެތެވެ. (އެއީ) ﷲގެ ހަޒުރަތުން ދެއްވާ ނަސްރަކާއި، އަދި ގާތްވެގެންވާ ފަތަޙެކެވެ. އަދި ކަލޭގެފާނު މުއުމިނު ތަކުންނަށް އުފާވެރިކަމުގެ ޚަބަރު ދެއްވާށެވެ!","",""],["","","","يا أيها الذين آمنوا كونوا أنصار الله كما قال عيسى ابن مريم للحواريين من أنصاري إلى الله قال الحواريون نحن أنصار الله فآمنت طائفة من بني إسرائيل وكفرت طائفة فأيدنا الذين آمنوا على عدوهم فأصبحوا ظاهرين","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުން ﷲއަށް ނަސްރު ދޭ ބަޔަކު ކަމުގައިވާށެވެ! މަރިޔަމްގެފާނުގެ ދަރިކަލުން ޢީސާގެފާނު، ޙަވާރިއްޔަންނަށް ވިދާޅުވި ފަދައިންނެވެ. ﷲއަށްޓަކައި ތިމަންކަލޭގެފާނަށް ނަސްރު ދޭނީ ކޮންބަޔެއްހެއްޔެވެ؟ ޙަވާރިއްޔަން ދެންނެވޫއެވެ. ތިމަންމެންނީ، ﷲއަށް ނަސްރު ދޭ މީހުންނެވެ. ދެން އިސްރާއީލުގެދަރިންކުރެ ޖަމާއަތެއް އީމާން ވޫއެވެ. އަދި އަނެއް ޖަމާއަތެއް ކާފިރު ވޫއެވެ. ފަހެ، އީމާންވި މީހުންނަށް އެއުރެންގެ އަދުއްވުންގެ މައްޗަށް ތިމަންރަސްކަލާނގެ ގަދަކަން ދެއްވީމެވެ. ފަހެ، އެއުރެންވީ، ބާރުލިބި، މަތިވެރިވެގެންވާ ބަޔަކު ކަމުގައެވެ.","",""],["","","","بسم الله الرحمن الرحيم يسبح لله ما في السماوات وما في الأرض الملك القدوس العزيز الحكيم","ރަސްވަންތަ، ތާހިރުވަންތަ، ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ﷲއަށް އުޑުތަކާއި، ބިމުގައިވާހާ ތަކެއްޗެއް ތަސްބީހަ ކިޔަތެވެ.","",""],["","","","هو الذي بعث في الأميين رسولا منهم يتلو عليهم آياته ويزكيهم ويعلمهم الكتاب والحكمة وإن كانوا من قبل لفي ضلال مبين","އުއްމީންގެ ތެރެޔަށް، އެއުރެންގެ ތެރެއިން ރަސޫލަކު ފޮނުއްވީ އެކަލާނގެއެވެ. އެކަލާނގެ އާޔަތްތައް އެއުރެންގެ މައްޗަށް އެކަލޭގެފާނު ކިޔަވައިދެއްވަތެވެ. އަދި އެއުރެން ތާހިރުކުރައްވަތެވެ. އަދި ފޮތާއި، ހިކުމަތެއުރެންނަށް އުނގަންނައިދެއްވަތެވެ. އޭގެކުރިން އެއުރެން ތިބީ ފާޅުވެ ބަޔާންވެގެންވާ އުރެދުމެއްގައިކަން ކަށަވަރެވެ.","",""],["","","","وآخرين منهم لما يلحقوا بهم وهو العزيز الحكيم","އަދި (އެކަލޭގެފާނު ފޮނުއްވީ) އެއުރެންގެ ތެރެއިން އެހެން ބަޔެއްގެ ގާތަށްވެސްމެއެވެ. އެއުރެންނީ، އެމީހުންގެ ތެރެއަށް އަދި ނާންނަ ބަޔެކެވެ. އަދި އެކަލާނގެއީ، ޢަޒީޒުވަންތަ ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ذلك فضل الله يؤتيه من يشاء والله ذو الفضل العظيم","އެއީ ﷲގެ ފަޟްލު ވަންތަކަމެވެ. އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް އެކަލާނގެ އެކަން ދެއްވަތެވެ. އަދި ﷲއީ، ބޮޑުވެގެންވާ ފަޟްލު ވަންތަކަމުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["","","","مثل الذين حملوا التوراة ثم لم يحملوها كمثل الحمار يحمل أسفارا بئس مثل القوم الذين كذبوا بآيات الله والله لا يهدي القوم الظالمين","ތައުރާތަށް ޢަމަލުކުރުމަށް އަންގަވާފައިވަނިކޮށް، ދެން އެއާއެއްގޮތަށް ޢަމަލު ނުކުރި މީހުންގެ މިސާލަކީ، ފޮތްތަކެއް އުފުލާ ހިމާރުގެ މިސާލެވެ. ﷲގެ އާޔަތްތައް ދޮގުކުރި މީހުންގެ މިސާލުގެ ހުރި ނުބައިކަމާއެވެ! އަދި އަނިޔާވެރި ބަޔަކަށް ﷲ ތެދުމަގެއް ނުދައްކަވަތެވެ.","",""],["","","","قل يا أيها الذين هادوا إن زعمتم أنكم أولياء لله من دون الناس فتمنوا الموت إن كنتم صادقين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ ޔަހޫދީވި މީހުންނޭވެ! ﷲގެ ހަޒުރަތުގައި އެހެން މީހުން ފިޔަވައި ގާތްބަޔަކީ، ތިޔަބައިމީހުން ކަމުގައި ތިޔަބައިމީހުން ހީކުރާނަމަ، ފަހެ، ތިޔަބައިމީހުން މަރުވުމަށް އެދިބަލާށެވެ! ތިޔަބައިމީހުންނީ، ތެދުބުނާ މީހުންކަމުގައި ވާނަމައެވެ.","",""],["","","","ولا يتمنونه أبدا بما قدمت أيديهم والله عليم بالظالمين","އަދި އެއުރެންގެ އަތްތައް އިސްކުރި ނުބައި ޢަމަލުގެ ސަބަބުން ދުވަހަކުވެސް އެއުރެން އެކަމަކަށް ނޭދޭނެތެވެ. ﷲއީ، އަނިޔާވެރިން މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","قل إن الموت الذي تفرون منه فإنه ملاقيكم ثم تردون إلى عالم الغيب والشهادة فينبئكم بما كنتم تعملون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، އެކަމަކުން ތިޔަބައިމީހުން ފިލަންދުވާ މަރު (ދަންނާށެވެ!) ފަހެ، އެ މަރު ތިޔަބައިމީހުންނާ ބައްދަލުކުރާނެކަން ކަށަވަރެވެ. ދެން ތިޔަބައިމީހުން ރައްދުކުރައްވާހުށީ، ނުފެންނަ ކަންތަކާއި، ފެންނަ ކަންތައް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެ ހަޒުރަތަށެވެ. ފަހެ، އޭރުން ތިޔަބައިމީހުން ކޮށްއުޅުނު ކަންތަކުގެ ޚަބަރު ތިޔަބައިމީހުންނަށް އެކަލާނގެ އަންގަވާނެތެވެ.","",""],["","","","يا أيها الذين آمنوا إذا نودي للصلاة من يوم الجمعة فاسعوا إلى ذكر الله وذروا البيع ذلكم خير لكم إن كنتم تعلمون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ހުކުރުދުވަހު (ހުކުރު) ނަމާދަށް ގޮވައިލާހިނދު ފަހެ، ﷲ ހަނދުމަކުރުމަށް (އެބަހީ: ޚުޠުބާ އަޑުއެހުމާއި، ނަމާދަށް) ތިޔަބައިމީހުން ހިނގައިގަންނާށެވެ! އަދި ވިޔަފާރިކުރުން ހުއްޓައިލާށެވެ! ތިޔަބައިމީހުން ދަންނަކަމުގައިވާނަމަ، އެގޮތް ތިޔަބައިމީހުންނަށް ހެޔޮކަން ބޮޑެވެ.","",""],["","","","فإذا قضيت الصلاة فانتشروا في الأرض وابتغوا من فضل الله واذكروا الله كثيرا لعلكم تفلحون","ފަހެ، ނަމާދުކޮށް އަވަދިވެއްޖެހިނދު، ފަހެ، ތިޔަބައިމީހުން ބިމުގައި ފެތުރިގަންނާށެވެ! (އެބަހީ: ހަޔާތްގެ މައިދާނަށް ނުކުންނާށެވެ!) އަދި ތިޔަބައިމީހުން ﷲގެ ފަޟްލު ވަންތަކަމުން (ދެއްވުމަށް) އެދޭށެވެ! އަދި ތިޔަބައިމީހުން ގިނަގިނައިން ﷲ ހަނދުމަކުރާށެވެ! އެއީ ތިޔަބައިމީހުން ދިންނަވައި ނަސީބު ލިބުމަށްޓަކައެވެ.","",""],["","","","وإذا رأوا تجارة أو لهوا انفضوا إليها وتركوك قائما قل ما عند الله خير من اللهو ومن التجارة والله خير الرازقين","އެއުރެންނަށް ވިޔަފާރިޔެއް ނުވަތަ ކުޅިވަރެއް ފެނިއްޖެނަމަ، ކަލޭގެފާނު ކޮޅަށް ހުންނެވުމަށް ދޫކޮށްލައި، އެއުރެން އެކަންތަކާ ދިމާޔަށް ދުވެދެއެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! ކުޅިވަރާއި، ވިޔަފާރިއަށްވުރެ، ﷲގެ ހަޒުރަތު ގައިވާ ދަރުމަ، ހެޔޮކަން ބޮޑެވެ. އަދި ﷲއީ، ރިޒްގު ދެއްވާ، އެންމެ ހެޔޮ ރަސްކަލާނގެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم إذا جاءك المنافقون قالوا نشهد إنك لرسول الله والله يعلم إنك لرسوله والله يشهد إن المنافقين لكاذبون","ކަލޭގެފާނުގެ އަރިހަށް މުނާފިގުން އަތުވެއްޖެހިނދު، އެއުރެން ބުނެތެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނީ، ﷲގެ ރަސޫލު އާކަމަށް ތިމަންމެން ހެކިވަމުއެވެ. ހަމަކަށަވަރުން، ކަލޭގެފާނީ، އެކަލާނގެ ރަސޫލު އާކަން ﷲ ދެނެވޮޑިގެންވެތެވެ. އަދި ހަމަކަށަވަރުން، މުނާފިގުންނީ، ދޮގުވެރިންކަމަށް ﷲ ހެކިވެވޮޑިގެންވެއެވެ.","",""],["","","","اتخذوا أيمانهم جنة فصدوا عن سبيل الله إنهم ساء ما كانوا يعملون","އެއުރެންގެ ހުވާތަކަކީ، އައްޑަނަތަކެއް ކަމުގައި އެއުރެން ހެދޫއެވެ. ފަހެ، އެއުރެން ﷲގެ މަގުން (މީސްތަކުން) އެއްކިބާކުރޫއެވެ. ހަމަކަށަވަރުން، އެއުރެން ކޮށްއުޅުނު ކަންތަކުގެ ނުބައިކަމާއެވެ!","",""],["","","","ذلك بأنهم آمنوا ثم كفروا فطبع على قلوبهم فهم لا يفقهون","އެއީ އެއުރެން އީމާންވެ، ދެން އެއަށްފަހު ކާފިރު ވީކަމުގެ ސަބަބުންނެވެ. ފަހެ، އެއުރެންގެ ހިތްތަކުގައިވަނީ ސިއްކަގައްސަވައިފައެވެ. ފަހެ، އެއުރެންނަކަށް ނުވިސްނެތެވެ.","",""],["","","","وإذا رأيتهم تعجبك أجسامهم وإن يقولوا تسمع لقولهم كأنهم خشب مسندة يحسبون كل صيحة عليهم هم العدو فاحذرهم قاتلهم الله أنى يؤفكون","އަދި ކަލޭގެފާނަށް އެއުރެން ފެނިވަޑައިގެންފިނަމަ، އެއުރެންގެ ހަށިތައް ކަލޭގެފާނު އަޖާއިބުކުރުވަތެވެ. އަދި އެއުރެން ވާހަކަ ދައްކާނަމަ، އެއުރެން ދައްކާ ވާހަކަ ކަލޭގެފާނު އައްސަވަމުއެވެ. އެއުރެންނީ (ފާރެއްގައި) ލައްގާފައިވާ ލަކުޑިތަކެއްފަދަ ބަޔެކެވެ. އެއުރެން ހީކުރަނީ، ކޮންމެ ހަޅޭކެއް އެއީ އެއުރެންގެ މައްޗަށް އަންނަ ހަމަލާއެއް ކަމުގައެވެ. އެއުރެންނީ، ހަމަ އަދާވަތް ތެރިންނެވެ. ފަހެ، ކަލޭގެފާނު އެއުރެންނާމެދު ރައްކާތެރިވެވަޑައިގަންނަވާށެވެ! ﷲ، އެއުރެންނަށް ލައުނަތް ލައްވާހުށްޓެވެ. އެއުރެން ހައްގުން އެއްކިބާވަނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","وإذا قيل لهم تعالوا يستغفر لكم رسول الله لووا رءوسهم ورأيتهم يصدون وهم مستكبرون","އަދި ﷲގެ ރަސޫލާ ތިޔަބައިމީހުންނަށް ފާފަފުއްސެވުމަށް ދުއާ ކޮށް ދެއްވުމަށްޓަކައި، ތިޔަބައިމީހުން އަންނާށޭ އެއުރެންގެ ގާތުގައި ބުނެފިނަމަ، އެއުރެންގެ ބޯތައް ހޫރުވައިލައެވެ. އަދި އެއުރެން ކިބުރުވެރިވެގެންވާ ޙާލުގައި، އެއުރެން ފުރަގަސްދީ ދާތީ ކަލޭގެފާނު ދެކެވަޑައިގަންނަވާނޫއެވެ.","",""],["","","","سواء عليهم أستغفرت لهم أم لم تستغفر لهم لن يغفر الله لهم إن الله لا يهدي القوم الفاسقين","އެއުރެންނަށް ފާފަފުއްސެވުމަށް ކަލޭގެފާނު ދުއާކުރެއްވިޔަސް، ނުވަތަ އެއުރެންނަށް ފާފަފުއްސެވުމަށް ކަލޭގެފާނު ދުއާ ނުކުރެއްވިޔަސް، އެއުރެންގެ މައްޗަށް ހަމަހަމަވެގެންވެއެވެ. ﷲ، އެއުރެންނަކަށް ފާފައެއް ނުފުއްސަވާނެތެވެ. އަދި ހަމަކަށަވަމުން، ފާސިގު ވީ މީހުންނަށް ﷲ ތެދުމަގެއް ނުދައްކަވާނެތެވެ.","",""],["","","","هم الذين يقولون لا تنفقوا على من عند رسول الله حتى ينفضوا ولله خزائن السماوات والأرض ولكن المنافقين لا يفقهون","އެއުރެން (ﷲގެ ރަސޫލާގެ އަރިހުން) ވަކިވެ ހިނގައްޖައުމަށް ދާނދެން ﷲގެ ރަސޫލާ އަރިހުގައި ތިބިބަޔަކަށް ތިޔަބައިމީހުން ހޭދަނުކުރާށޭ ބުނާމީހުންނީ، އެއުރެންނެވެ. އަދި އުޑުތަކާއި، ބިމުގައިވާ ޚަޒާނާތައް މިލްކުވެގެންވަނީ، ﷲއަށެވެ. އެހެނެއްކަމަކު މުނާފިގުންނަކަށް (އެކަމެއް) ނުވިސްނެތެވެ.","",""],["","","","يقولون لئن رجعنا إلى المدينة ليخرجن الأعز منها الأذل ولله العزة ولرسوله وللمؤمنين ولكن المنافقين لا يعلمون","އެއުރެން ބުނެތެވެ. ހަމަކަށަވަރުން، ތިމަންމެން އެނބުރި މަދީނާއަށް އަތުވެއްޖެނަމަ، ހަމަކަށަވަރުން، އެންމެ ޢިއްޒަތް ތެރި މީހާ، އެންމެ ދެރަ ނިކަމެތި މީހާ އެތަނުން ބޭރުކޮށްލާނެތެވެ. (އެހެންނަކުން ނޫނެވެ.) ޢިއްޒަތް ވަނީ، ﷲއަށެވެ. އަދި އެކަލާނގެ ރަސޫލާއަށާއި، މުއުމިނުންނަށެވެ. އެހެނެއްކަމަކު މުނާފިގުންނަކަށް (އެކަމެއް) ނޭނގެތެވެ.","",""],["","","","يا أيها الذين آمنوا لا تلهكم أموالكم ولا أولادكم عن ذكر الله ومن يفعل ذلك فأولئك هم الخاسرون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ މުދާތަކާއި، ތިޔަބައިމީހުންގެ ދަރިންތައް ﷲ ހަނދުމަކުރުމުން ތިޔަބައިމީހުން މަޝްޣޫލު ކޮށް ދުރުކުރިޔަ ނުދޭހުށިކަމެވެ! އަދި އެކަންތައްކުރާ މީހާ (ދަންނާށެވެ!) ފަހެ، ގެއްލެނިވެގެންވާ މީހުންނީ، ހަމަ އެއުރެންނެވެ.","",""],["","","","وأنفقوا من ما رزقناكم من قبل أن يأتي أحدكم الموت فيقول رب لولا أخرتني إلى أجل قريب فأصدق وأكن من الصالحين","އަދި ތިޔަބައިމީހުންކުރެ މީހެއްގެ ގާތަށް މަރު އައުމުގެ ކުރީގައި، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް ދެއްވި ތަކެތިން ތިޔަބައިމީހުން ހޭދަކުރާށެވެ! ފަހެ، (އެހިނދު) އޭނާ ބުނާނެތެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ކައިރި އަޖަލަކަށް އިބަރަސްކަލާނގެ މިއަޅާ ފަސްކުރައްވާނެނަމަ ކޮންފަދަތޯއެވެ؟ ފަހެ، އޭރުން ތިމަންއަޅާ ސަދަގާތް ކޮށް، ސާލިހު އަޅުންގެ ތެރެއިން ވާހުށީމެވެ.","",""],["","","","ولن يؤخر الله نفسا إذا جاء أجلها والله خبير بما تعملون","އަދި ﷲ، އެއްވެސް ނަފްސެއް، އޭގެ އަޖަލު އަންނަހިނދު، ފަހެއް ނުކުރައްވާނެތެވެ. އަދި ﷲއީ، ތިޔަބައިމީހުންކުރާ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم يسبح لله ما في السماوات وما في الأرض له الملك وله الحمد وهو على كل شيء قدير","އުޑުތަކާއި، ބިމުގައިވާހާ ތަކެއްޗެއް ﷲއަށް ތަސްބީހަ ކިޔަތެވެ. ވެރިކަންވަނީ އެކަލާނގެއަށެވެ. އަދި ހަމްދު ހުރީވެސް އެކަލާނގެއަށެވެ. އަދި އެކަލާނގެއީ، ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","هو الذي خلقكم فمنكم كافر ومنكم مؤمن والله بما تعملون بصير","އެކަލާނގެއީ، ތިޔަބައިމީހުން ހެއްދެވި ރަސްކަލާނގެއެވެ. ފަހެ، ތިޔަބައިމީހުންގެ ތެރެއިން ކާފިރުން ވެއެވެ. އަދި ތިޔަބައިމީހުންގެ ތެރެއިން މުއުމިނު ންވެސް ވެއެވެ. އަދި ﷲއީ، ތިޔަބައިމީހުންކުރާ ކަންތައް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","خلق السماوات والأرض بالحق وصوركم فأحسن صوركم وإليه المصير","އެކަލާނގެ އުޑުތަކާއި، ބިން ހައްގު ގޮތުގައި ހެއްދެވިއެވެ. އަދި ތިޔަބައިމީހުން ޞޫރަކުރައްވައި، ދެން ތިޔަބައިމީހުންގެ ޞޫރަތައް ރިވެތިކުރެއްވިއެވެ. އަދި އެނބުރި ދިޔުންވަނީ، އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","يعلم ما في السماوات والأرض ويعلم ما تسرون وما تعلنون والله عليم بذات الصدور","އުޑުތަކާއި، ބިމުގައިވާހާކަމެއް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަދި ތިޔަބައިމީހުން ސިއްރުކުރާ ކަންތަކާއި، ފާޅުކުރާ ކަންތައް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަދި ﷲއީ، ހިތްތަކުގައިވާހާކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ألم يأتكم نبأ الذين كفروا من قبل فذاقوا وبال أمرهم ولهم عذاب أليم","މީގެކުރިން ކާފިރު ވިމީހުންގެ ޚަބަރު، ތިޔަބައިމީހުންނާ ހަމަޔަކަށް ނާދޭހެއްޔެވެ؟ ފަހެ، އެއުރެންކުޅަ ކަންތަކުގެ ނުބައި ނަތީޖާގެ ރަހަ، އެއުރެން ލިބިގަތޫއެވެ. އަދި އެއުރެންނަށް ވޭންދެނިވި އަޒާބު ހުށްޓެވެ.","",""],["","","","ذلك بأنه كانت تأتيهم رسلهم بالبينات فقالوا أبشر يهدوننا فكفروا وتولوا واستغنى الله والله غني حميد","އެއީ އެއުރެންގެ ގާތަށް އެއުރެންގެ ރަސޫލުން ފާޅުވެގެންވާ ހެކިތަކާއިގެން ވަޑައިގަތުމުން، ފަހެ، ތިމަންމެންނަށް ތެދުމަގު ދައްކަނީ، އާދަމުގެދަރިންތަކެއް ހެއްޔޭ، އެއުރެން ބުނެ، އެއުރެން ކާފިރުވެ، ފުރަގަސްދިނީތީއެވެ. އަދި ﷲ ފުދިވޮޑިގެންވެއެވެ. ﷲއީ، ފުދިވޮޑިގެންވާ، ހަމްދު ލިބިވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","زعم الذين كفروا أن لن يبعثوا قل بلى وربي لتبعثن ثم لتنبؤن بما عملتم وذلك على الله يسير","ކާފިރު ވިމީހުން، އެއުރެން އަލުން ދިރުއްވައި ނުފޮނުއްވާނޭކަމަށް ހީކުރޫއެވެ. ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެހެންނަކުން ނޫނެވެ. ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ގަންދެއްވައި ވިދާޅުވަމެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުން އަލުން ދިރުއްވައި ފޮނުއްވާހުށްޓެވެ. ދެން ހަމަކަށަވަރުން، ތިޔަބައިމީހުންކުރި ޢަމަލުތަކުގެ ޚަބަރު، ތިޔަބައިމީހުންނަށް އަންގަވާހުށްޓެވެ. އަދި އެކަންތަކަކީ، ﷲއަށް ދާދިފަސޭހަ ކަމެކެވެ.","",""],["","","","فآمنوا بالله ورسوله والنور الذي أنزلنا والله بما تعملون خبير","ފަހެ، ތިޔަބައިމީހުން ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށާއި، ތިމަންރަސްކަލާނގެ ބާވައިލެއްވި ނޫރަށް (އެބަހީ: ގުރްއާނަށް) އީމާން ވާށެވެ! ﷲއީ، ތިޔަބައިމީހުންކުރާ ކަންތައް، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","يوم يجمعكم ليوم الجمع ذلك يوم التغابن ومن يؤمن بالله ويعمل صالحا يكفر عنه سيئاته ويدخله جنات تجري من تحتها الأنهار خالدين فيها أبدا ذلك الفوز العظيم","އެއްކުރެއްވުމުގެ ދުވަހަށް، އެކަލާނގެ ތިޔަބައިމީހުން އެއްކުރައްވާ ދުވަސް (ހަނދުމަކުރާށެވެ!) އެއީ ތަޣާބުނުގެ ދުވަހެވެ. (އެބަހީ: ގިޔާމަތް ދުވަހެވެ.) ﷲއަށް އީމާންވެ، ސާލިހު ޢަމަލުކުރާ މީހާޔަށް އޭނާގެ ކުށްތައް އެކަލާނގެ އޭނާގެ ކިބައިން ފުއްސަވާނެތެވެ. އަދި އެތާނގެ ދަށުން ފެންކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކަށް އެކަލާނގެ އޭނާ ވައްދަވާނެތެވެ. އެތާނގައި، އަބަދަށް ދެމިތިބެނިވި ގޮތުގައެވެ. ބޮޑުވެގެންވާ ނަސީބު ލިބުމަކީ އެއީއެވެ.","",""],["","","","والذين كفروا وكذبوا بآياتنا أولئك أصحاب النار خالدين فيها وبئس المصير","އަދި ކާފިރުވެ، ތިމަންރަސްކަލާނގެ އާޔަތްތައް ދޮގުކުޅަމީހުން (ދަންނާށެވެ!) އެއުރެންނީ، ނަރަކައިގެ އަހުލުވެރިންނެވެ. އެތާނގައި އެއުރެން ދެމިތިބެނިވި ގޮތުގައެވެ. އަދި އެއީ ހާދަހާ ނުބައިވެގެންވާ ނިމިދިޔުމެކެވެ.","",""],["","","","ما أصاب من مصيبة إلا بإذن الله ومن يؤمن بالله يهد قلبه والله بكل شيء عليم","ﷲގެ އިޒުނަ ފުޅަށްމެނުވީ، އެއްވެސް މުސީބަތެއް ނުޖެހެއެވެ. އަދި ﷲއަށް އީމާން ވާމީހާ (ދަންނާށެވެ!) އެކަލާނގެ އެމީހާގެ ހިތަށް ތެދުމަގު ދައްކަވަތެވެ. ﷲއީ، ކޮންމެކަމެއް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","وأطيعوا الله وأطيعوا الرسول فإن توليتم فإنما على رسولنا البلاغ المبين","ތިޔަބައިމީހުން ﷲއަށް ކިޔަމަންވާށެވެ! އަދި ތިޔަބައިމީހުން ރަސޫލާއަށް ކިޔަމަންވާށެވެ! ފަހެ، ތިޔަބައިމީހުން (އެކަމަށް) ފުރަގަސްދީފިނަމަ، ފަހެ، ތިމަންރަސްކަލާނގެ ރަސޫލާގެ މައްޗަށް އޮތްކަން ކަށަވަރީ، ބަޔާން ވެގެންވާ އިއްވެވުމެވެ.","",""],["","","","الله لا إله إلا هو وعلى الله فليتوكل المؤمنون","ﷲއީ، އެކަލާނގެ ފިޔަވައި ހައްގު ވެގެން އަޅުކަމެއްވެވޭ އިލާހަކުނުވާ ރަސްކަލާނގެއެވެ. ފަހެ، މުއުމިނު ތަކުން، ހަމައެކަނި ﷲއަށް ވަކީލުކުރާ ހުށިކަމެވެ!","",""],["","","","يا أيها الذين آمنوا إن من أزواجكم وأولادكم عدوا لكم فاحذروهم وإن تعفوا وتصفحوا وتغفروا فإن الله غفور رحيم","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ އަނބީންނާއި، ތިޔަބައިމީހުންގެ ދަރިންގެ ތެރެއިން، ތިޔަބައިމީހުންނަށް އަދާވަތް ތެރިންވެއެވެ. ފަހެ، އެއުރެންނަށް ތިޔަބައިމީހުން ރައްކާތެރިވެ ތިބޭށެވެ! ތިޔަބައިމީހުން އަފޫ ކޮށް، މާފުކޮށް، އަދި ކުށަކަށް ނުހަދައިފިނަމަ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","إنما أموالكم وأولادكم فتنة والله عنده أجر عظيم","ތިޔަބައިމީހުންގެ މުދާތަކާއި، ތިޔަބައިމީހުންގެ ދަރިންތައް ވާކަންކަށަވަރީ، އިމްތިހާނެއް ކަމުގައެވެ. އަދި ބޮޑުވެގެންވާ ދަރުމަހުރީ، ﷲގެ ހަޒުރަތު ގައެވެ.","",""],["","","","فاتقوا الله ما استطعتم واسمعوا وأطيعوا وأنفقوا خيرا لأنفسكم ومن يوق شح نفسه فأولئك هم المفلحون","ފަހެ، ތިޔަބައިމީހުންނަށް ކުޅަދާނަވީވަރަކުން، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އަދި ތިޔަބައިމީހުން އަހާށެވެ! އަދި ތިޔަބައިމީހުން ކިޔަމަންވާށެވެ! އަދި ތިޔަބައިމީހުން ހޭދަކުރާށެވެ! ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސުތަކަށް އެގޮތް ހެޔޮކަން ބޮޑުވެގެންވެއެވެ. އަދި އެމީހެއްގެ އަމިއްލަ ނަފްސުގެ ދަހިވެތިކަމުން މިންޖުވެއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ ހަމަ ދިންނަވާނޭ މީހުންނެވެ.","",""],["","","","إن تقرضوا الله قرضا حسنا يضاعفه لكم ويغفر لكم والله شكور حليم","ހެޔޮވެގެންވާ ދަރަންޏަކުން ﷲއަށް ތިޔަބައިމީހުން ދަރަންޏެއް ދޭނަމަ (އެބަހީ: ﷲއަށްޓަކައި ހޭދަކުރާނަމަ) އެކަލާނގެ ތިޔަބައިމީހުންނަށްޓަކައި، އެތަކެތި ގިނަގުނަކުރައްވާނެތެވެ. އަދި އެކަލާނގެ ތިޔަބައިމީހުންނަށް ފާފަފުއްސަވާނެތެވެ. ﷲއީ، ގިނަގިނައިން ޝުކުރު ގަބޫލުކުރައްވާ، ހަލީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","عالم الغيب والشهادة العزيز الحكيم","(އެކަލާނގެއީ) ނުފެންނަ ކަންތަކާއި، ފެންނަ ކަންތައް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. ޢަޒީޒުވަންތަ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم يا أيها النبي إذا طلقتم النساء فطلقوهن لعدتهن وأحصوا العدة واتقوا الله ربكم لا تخرجوهن من بيوتهن ولا يخرجن إلا أن يأتين بفاحشة مبينة وتلك حدود الله ومن يتعد حدود الله فقد ظلم نفسه لا تدري لعل الله يحدث بعد ذلك أمرا","އޭ ނަބިއްޔާއެވެ! ތިޔަބައިމީހުން އަނބިން ވަރިކުރާނަމަ، ފަހެ، އެކަނބަލުންގެ އިއްދަށް (ފެށޭގޮތުގައި ސުންނީ ވަރިޔަކުން) ތިޔަބައިމީހުން އެކަނބަލުން ވަރިކުރާށެވެ! އަދި ތިޔަބައިމީހުން އިއްދަ ގުނާހަމަކުރާށެވެ! އަދި ތިޔަބައިމީހުންގެ ވެރި ﷲއަށް، ތިޔަބައިމީހުން ތަގުވާވެރިވާށެވެ! ތިޔަބައިމީހުން އެކަނބަލުންގެ ގެތަކުން އެކަނބަލުން ނުނެރޭށެވެ! އަދި އެކަނބަލުންވެސް ނުނިކުންނަ ހުށިކަމެވެ! ފާޅުވެ ހުތުރުކަން ބޮޑުވެގެންވާ ފާފަޔެއް އެކަނބަލުން ގެނެސްފިއްޔާ މެނުވީއެވެ. އަދި އެއީ، ﷲ ކަނޑައަޅުއްވާފައިވާ އިންތަކެވެ. އަދި ﷲ ކަނޑައަޅުއްވާފައިވާ އިންތައް ފަހަނަޅައިދާމީހާ (ދަންނާށެވެ!) ފަހެ، އެމީހާގެ އަމިއްލަ ނަފްސަށް އެމީހާ އަނިޔާވެރިވެއްޖެކަން ކަށަވަރެވެ. އެއަށްފަހު (އެބަހީ: ވަރިކުރުމަށްފަހު) ﷲ އެހެންގޮތެއް މެދުވެރިކުރައްވައިފާނެކަންވެސް ތިބާޔަކަށް ނޭނގެތެވެ.","",""],["","","","فإذا بلغن أجلهن فأمسكوهن بمعروف أو فارقوهن بمعروف وأشهدوا ذوي عدل منكم وأقيموا الشهادة لله ذلكم يوعظ به من كان يؤمن بالله واليوم الآخر ومن يتق الله يجعل له مخرجا","ފަހެ، އެކަނބަލުންގެ އިއްދަ ހަމަވުމާ ގާތްވެއްޖެހިނދު، ހެޔޮގޮތުގައި ތިޔަބައިމީހުން އެކަނބަލުން ހިފަހައްޓާށެވެ! (އެބަހީ: ކާވެނި ރުޖޫއަކުރާށެވެ!) ނުވަތަ ހެޔޮގޮތުގައި އެކަނބަލުންނާ ވަކިވާށެވެ! އަދި ތިޔަބައިމީހުންގެ ތެރެއިން ޢަދުލުވެރި ދެމީހުން ހެކިކުރާށެވެ! އަދި ﷲއަށްޓަކައި ތިޔަބައިމީހުންގެ ހެކިބަސް އަދާކުރާށެވެ! ﷲއަށާއި، އާޚިރަތް ދުވަހަށް އީމާންވާ މީހުންނަށް ނަސޭހަތް ދެއްވާފައިވާ ގޮތަކީ އެއީއެވެ. އަދި ﷲއަށް ތަގުވާވެރިވާމީހާ (ދަންނާށެވެ!) އެކަލާނގެ އޭނާޔަށް ނުކުންނާނެ މަގެއް ދައްކަވާނެތެވެ.","",""],["","","","ويرزقه من حيث لا يحتسب ومن يتوكل على الله فهو حسبه إن الله بالغ أمره قد جعل الله لكل شيء قدرا","އަދި ހީވެސްނުކުރާފަދަ ގޮތްގޮތުން އެކަލާނގެ އޭނާޔަށް ރިޒްގު ދެއްވާނެތެވެ. އަދި ﷲއަށް ވަކީލުކުރާމީހާ (ދަންނާށެވެ!) ފަހެ، އޭނާޔަށް އެކަލާނގެ ފުދެއެވެ. ހަމަކަށަވަރުން، ﷲއީ، އެކަލާނގެ އަމުރުފުޅު ހިންގަވައި، ފުރިހަމަކުރައްވާ ރަސްކަލާނގެއެވެ. ހަމަކަށަވަރުން، ﷲ ކޮންމެ އެއްޗަކަށް މިންވަރެއް ކަނޑައަޅުއްވާފައިވެއެވެ.","",""],["","","","واللائي يئسن من المحيض من نسائكم إن ارتبتم فعدتهن ثلاثة أشهر واللائي لم يحضن وأولات الأحمال أجلهن أن يضعن حملهن ومن يتق الله يجعل له من أمره يسرا","އަދި ތިޔަބައިމީހުންގެ އަންހެނުންކުރެ ހައިޟުން އުންމީދު ކެނޑިފައިވާ މީހުންނާމެދު (އެބަހީ: އިއްދަ އިން ކެނޑިފައިވާ އަންހެނުންނާމެދު) ތިޔަބައިމީހުން ޝައްކުކުރާނަމަ، ފަހެ، އެކަނބަލުންގެ އިއްދަކީ، އަދި ހައިޟު ނުވާ މީހުންގެ އިއްދަކީވެސް ތިންމަސް ދުވަހެވެ. އަދި މާބަނޑު އަންހެނުންގެ އިއްދަކީ، އެކަނބަލުން ބަނޑުގައިވާ ދަރި ވިހެއުމެވެ. އަދި ﷲއަށް ތަގުވާވެރިވާމީހާ (ދަންނާށެވެ!) އޭނާގެ ކަންތަކުގައި އެކަލާނގެ އޭނާޔަށް ފަސޭހަކަން ލައްވާނެތެވެ.","",""],["","","","ذلك أمر الله أنزله إليكم ومن يتق الله يكفر عنه سيئاته ويعظم له أجرا","އެއީ ތިޔަބައިމީހުންނަށް ﷲ ބާވައިލެއްވި، އެކަލާނގެ އަމުރު ފުޅެވެ. އަދި ﷲއަށް ތަގުވާވެރިވެއްޖެމީހާ (ދަންނާށެވެ!) އެކަލާނގެ އޭނާގެ ކިބައިން އޭނާގެ ކުށްތައް ފުއްސަވާނެތެވެ. އަދި އެކަލާނގެ އޭނާއަށް ދަރުމަ ބޮޑުކުރައްވާނެތެވެ.","",""],["","","","أسكنوهن من حيث سكنتم من وجدكم ولا تضاروهن لتضيقوا عليهن وإن كن أولات حمل فأنفقوا عليهن حتى يضعن حملهن فإن أرضعن لكم فآتوهن أجورهن وأتمروا بينكم بمعروف وإن تعاسرتم فسترضع له أخرى","ތިޔަބައިމީހުންގެ ތަނަވަސްކަން ހުރިވަރަކުން ތިޔަބައިމީހުން އުޅޭ ތަނެއްގައި އެކަނބަލުން (އެބަހީ: ވަރިކޮށްފައި، އިއްދަގައި ތިބޭ އަންހެނުން) ބައިތިއްބާށެވެ! އަދި އެކަނބަލުންނަށް ދަތިކުރުމަށްޓަކައި، ތިޔަބައިމީހުން އެކަނބަލުންނަށް ގެއްލުން ނުދޭށެވެ! އަދި މާބަނޑު އަންހެނުން ކަމުގައި އެކަނބަލުން ވެއްޖެނަމަ، ފަހެ، އެކަނބަލުން ދަރި ވިހައިފުމަށް ދާނދެން ތިޔަބައިމީހުން އެކަނބަލުންނަށް ޚަރަދުކުރާށެވެ! ފަހެ، ތިޔަބައިމީހުންނަށްޓަކައި (ތިޔަބައިމީހުންގެ ދަރިންނަށް) އެކަނބަލުން ކިރުދީފިނަމަ، ފަހެ، ތިޔަބައިމީހުން އެކަނބަލުންނަށް، އެކަނބަލުންގެ އުޖޫރަދޭށެވެ! އަދި ތިޔަބައިމީހުންގެ މެދުގައި ހެޔޮގޮތުގައި އެކަކު އަނެކަކާ މަޝްވަރާކުރާށެވެ! އަދި ތިޔަބައިމީހުންނަށް ދަތިވެއްޖެނަމަ، އޭނާޔަށްޓަކައި، ފަހެ، (އެކުއްޖާޔަށް) އެހެން އަންހެނަކު ކިރުދޭނީއެވެ.","",""],["","","","لينفق ذو سعة من سعته ومن قدر عليه رزقه فلينفق مما آتاه الله لا يكلف الله نفسا إلا ما آتاها سيجعل الله بعد عسر يسرا","ތަނަވަސްކަމުގެ ވެރިޔާ، އޭނާގެ ތަނަވަސްކަންހުރި މިންވަރަކުން ހޭދަކުރާހުށިކަމެވެ! އަދި އެމީހެއްގެ ރިޒްގު ދަތިކުރައްވާފައިވާ މީހާ، ފަހެ، އެމީހާޔަށް ﷲ ދެއްވި އެއްޗަކުން ހޭދަކުރާހުށިކަމެވެ! އެއްވެސް ނަފްސަކަށް، އެ ނަފްސަކަށް ދެއްވާފައިވާ އެއްޗެއްގެ މިންވަރުން މެނުވީ، ﷲ ތަކުލީފެއް ނުޖައްސަވަތެވެ. ދަތިކަމަކަށްފަހު، ފަސޭހަކަމެއް، ﷲ ލައްވާހުށްޓެވެ.","",""],["","","","وكأين من قرية عتت عن أمر ربها ورسله فحاسبناها حسابا شديدا وعذبناها عذابا نكرا","އެ ރަށްރަށުގެ އަހުލުވެރިން އެއުރެންގެ ވެރިރަސްކަލާނގެ އަމުރު ފުޅަށާއި، އެކަލާނގެ ރަސޫލުންނަށް ނުކިޔަމަންތެރިވީ ކިތައްކިތައް ރަށްހެއްޔެވެ؟ ފަހެ، ތިމަންރަސްކަލާނގެ އެއުރެންނާ މެދުގައި ގަދަވެގެންވާ ހިސާބަކުން ހިސާބު ބައްލަވައި، ބިރުވެރި އަޒާބަކުން، އެއުރެންނަށް އަޒާބު ދެއްވީމެވެ.","",""],["","","","فذاقت وبال أمرها وكان عاقبة أمرها خسرا","ފަހެ، އެއުރެންކުޅަ ކަންތަކުގެ ނަތީޖާގެ ރަހަ އެއުރެންނަށް ލިބުނެވެ. އަދި އެއުރެންގެ އެކަންތަކުގެ ނިމުންވީ ގެއްލުމެއް ކަމުގައެވެ.","",""],["","","","أعد الله لهم عذابا شديدا فاتقوا الله يا أولي الألباب الذين آمنوا قد أنزل الله إليكم ذكرا","ﷲ، އެއުރެންނަށްޓަކައި ގަދަވެގެންވާ އަޒާބެއް ތައްޔާރުކުރެއްވިއެވެ. ފަހެ، ތިޔަބައިމީހުން ﷲއަށް ތަގުވާވެރިވާށެވެ! އޭ އީމާން ވެގެންތިބި ބުއްދީގެ އަހުލުވެރިންނޭވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ގާތަށް ހަނދާންކޮށްދެއްވުމެއް ﷲ ބާވައިލެއްވިއެވެ.","",""],["","","","رسولا يتلو عليكم آيات الله مبينات ليخرج الذين آمنوا وعملوا الصالحات من الظلمات إلى النور ومن يؤمن بالله ويعمل صالحا يدخله جنات تجري من تحتها الأنهار خالدين فيها أبدا قد أحسن الله له رزقا","ﷲގެ ބަޔާން ވެގެންވާ އާޔަތްތައް ތިޔަބައިމީހުންގެ މައްޗަށް ކިޔަވައިދެއްވާ ރަސޫލަކު ފޮނުއްވިއެވެ. (އެއީ) އީމާންވެ، ސާލިހު ޢަމަލުކުރި މީހުން، އަނދިރިކަމުގެ ތެރެއިން އަލިކަމުގެ ތެރެޔަށް، ނެރުއްވުމަށްޓަކައެވެ. އަދި ﷲއަށް އީމާންވެ، ސާލިހު ޢަމަލުކުރާމީހާ (ދަންނާށެވެ!) އެތަންތާނގެ ދަށުން ކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތަކަށް، އެކަލާނގެ އޭނާ ވައްދަވާނެތެވެ. އެތާނގައި، އެއުރެން އަބަދަށް ދެމިތިބެނިވި ގޮތުގައެވެ. ހަމަކަށަވަރުން، އެންމެ ފުރިހަމަ ގޮތުގައި ﷲ، އޭނާޔަށް ރިޒްގު ދެއްވިއެވެ.","",""],["","","","الله الذي خلق سبع سماوات ومن الأرض مثلهن يتنزل الأمر بينهن لتعلموا أن الله على كل شيء قدير وأن الله قد أحاط بكل شيء علما","ﷲއީ، ހަތް އުޑު ހެއްދެވި ރަސްކަލާނގެއެވެ. އަދި ބިމުންވެސް އެފަދަމެއެވެ. (އެބަހީ: އެކަލާނގެ ހަތް ބިން ހެއްދެވިއެވެ.) އެތަންތާނގައި އެކަލާނގެ އަމުރުފުޅު ހިނގަހިނގާ ހުރެތެވެ. ހަމަކަށަވަރުން ﷲއީ، ކޮންމެ ކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެކަމާއި، ހަމަކަށަވަރުން، ﷲގެ އިލްމުފުޅު، ހުރިހާ އެއްޗެއްގެ ވަށައިގެންވާކަން ތިޔަބައިމީހުންނަށް އެނގުމަށްޓަކައެވެ.","",""],["","","","بسم الله الرحمن الرحيم يا أيها النبي لم تحرم ما أحل الله لك تبتغي مرضات أزواجك والله غفور رحيم","އޭ ނަބިއްޔާއެވެ! ﷲ، ކަލޭގެފާނަށް ހަލާލުކުރައްވާފައިވާ ކަމެއް، ކަލޭގެފާނުގެ އަނބިއަނބިކަނބަލުންގެ ރުހުން ހޯއްދެވުމަށްޓަކައި ކަލޭގެފާނު ހަރާމްކުރައްވަނީ ކީއްވެގެންތޯއެވެ؟ ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","قد فرض الله لكم تحلة أيمانكم والله مولاكم وهو العليم الحكيم","ތިޔަބައިމީހުންގެ ހުވާތަކުން ބަރީއަވާނޭގޮތް، ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށްޓަކައި ﷲ ކަނޑައަޅުއްވައިފިއެވެ. ﷲއީ، ތިޔަބައިމީހުންގެ އެހީތެރިވަންތަ ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެއީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","وإذ أسر النبي إلى بعض أزواجه حديثا فلما نبأت به وأظهره الله عليه عرف بعضه وأعرض عن بعض فلما نبأها به قالت من أنبأك هذا قال نبأني العليم الخبير","ނަބިއްޔާ، އެކަލޭގެފާނުގެ ބައެއް އަނބިކަނބަލުންގެ އަރިހުގައި (އެބަހީ: ޙަފްޞާގެފާނުގެ އަރިހުގައި) ވާހަކައެއް ސިއްރުން ވިދާޅުވިހިނދު ހަނދުމަކުރާށެވެ! ފަހެ، އެކަމަނާ އެވާހަކައިން (ޢާއިޝާގެފާނަށް) ޚަބަރުކުރެއްވިހިނދު، އަދި ﷲ، އެކަލޭގެފާނަށް އެކަން ފާޅުކުރެއްވުމުން، އެވާހަކައިން ބައެއް އެކަލޭގެފާނު (އެކަމަނާއަށް) އަންގަވައި، އަނެއްބައި ނާންގަވައި ދޫކޮށްލެއްވިއެވެ. ފަހެ، އެކަމަނާއަށް އެވާހަކައިން އެކަލޭގެފާނު ޚަބަރުކުރެއްވުމުން އެކަމަނާ ވިދާޅުވިއެވެ. ކަލޭގެފާނަށް މި ޚަބަރު ދިނީ ކާކުތޯއެވެ؟ އެކަލޭގެފާނު ވިދާޅުވިއެވެ. ތިމަންކަލޭގެފާނަށް އެ ޚަބަރު އެންގެވީ، މޮޅަށް ދެނެވޮޑިގެންވާ، ޚައިބަރުވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","إن تتوبا إلى الله فقد صغت قلوبكما وإن تظاهرا عليه فإن الله هو مولاه وجبريل وصالح المؤمنين والملائكة بعد ذلك ظهير","ތިޔަ ދެބޭކަނބަލުން ﷲއަށް ތައުބާ ވާނަމަ (އެގޮތް ތިޔަ ދެބޭކަނބަލުންނަށް ހެޔޮކަން ބޮޑެވެ.) ފަހެ، ތިޔަ ދެބޭކަނބަލުންގެ ހިތްޕުޅު (ރަސޫލާ އެދިވަޑައިގަންނަވާ ކަންތަކުން) އެއްކިބާވެއްޖެކަން ކަށަވަރެވެ. އަދި ތިޔަ ދެބޭކަނބަލުން އެކަލޭގެފާނާ ދެކޮޅަށް އެކަކު އަނެކަކަށް ވާގިވެރިވާނަމަ، ފަހެ، ހަމަކަށަވަރުން، ﷲއީ، އެކަލޭގެފާނުގެ އެހީތެރިވަންތަ ރަސްކަލާނގެއެވެ. އަދި ޖިބްރީލުގެފާނާއި، ސާލިހު މުއުމިނު ންވެސްމެއެވެ. އަދި އެއަށްފަހު، މަލާއިކަތް ންވެސް، އެކަލޭގެފާނުގެ އެހީތެރިން ކަމުގައިވެއެވެ.","",""],["","","","عسى ربه إن طلقكن أن يبدله أزواجا خيرا منكن مسلمات مؤمنات قانتات تائبات عابدات سائحات ثيبات وأبكارا","އެކަލޭގެފާނު، ތިޔަކަނބަލުން ވަރިކުރައްވައިފިނަމަ، ތިޔަކަނބަލުންނަށްވުރެ ހެޔޮކަންބޮޑު އަނބިންތަކެއް، އޭގެބަދަލުގައި އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެކަލޭގެފާނަށް ދެއްވައިފާނެތެވެ. (އެއީ) އިސްލާމް ވެގެންވާ، އީމާން ވެގެންވާ، ކިޔަމަންވާ، ތައުބާވާ، އަޅުވެރި، ރޯދަހިފާ، ބިކުރުވެރިނޫން އަނބިންނާއި، ބިކުރުވެރި އަނބިންނެވެ.","",""],["","","","يا أيها الذين آمنوا قوا أنفسكم وأهليكم نارا وقودها الناس والحجارة عليها ملائكة غلاظ شداد لا يعصون الله ما أمرهم ويفعلون ما يؤمرون","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސު ތަކާއި، ތިޔަބައިމީހުންގެ އަހުލުވެރިން، ނަރަކައިން ސަލާމަތްކުރާށެވެ! އެ ނަރަކައިގެ ދަރަކީ، މީހުންނާއި ހިލައެވެ. އެ ނަރަކައިގެ މައްޗަށް (ބަނޑޭރިންކަމުގައި) ހަރުކަށި، އަދި ގަދަފަދަ މަލާއިކަތް ންވެއެވެ. ﷲ، އެބޭކަލުންނަށް ކުރައްވާ އަމުރަކަށް އެބޭކަލުން ނުއުރެދޭނެތެވެ. އަދި އެބޭކަލުންނަށް އަމުރުކުރައްވާކަންތައް އެބޭކަލުން ކުރައްވާނެތެވެ.","",""],["","","","يا أيها الذين كفروا لا تعتذروا اليوم إنما تجزون ما كنتم تعملون","އޭ ކާފިރު ވެއްޖެ މީސްތަކުންނޭވެ! މިއަދު ތިޔަބައިމީހުން އުޒުރު ނުދައްކާށެވެ! ތިޔަބައިމީހުންނަށް ޖަޒާދެއްވާކަން ކަށަވަރީ، ތިޔަބައިމީހުން ކޮށްއުޅުނު ކަންތަކަށެވެ.","",""],["","","","يا أيها الذين آمنوا توبوا إلى الله توبة نصوحا عسى ربكم أن يكفر عنكم سيئاتكم ويدخلكم جنات تجري من تحتها الأنهار يوم لا يخزي الله النبي والذين آمنوا معه نورهم يسعى بين أيديهم وبأيمانهم يقولون ربنا أتمم لنا نورنا واغفر لنا إنك على كل شيء قدير","އޭ އީމާން ވެއްޖެ މީސްތަކުންނޭވެ! ތެދުވެރި، އިހްލާސް ތެރި ތައުބާއަކުން، ތިޔަބައިމީހުން ﷲއަށް ތައުބާ ވާށެވެ! އޭރުން ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ، ތިޔަބައިމީހުންގެ ކިބައިން، ތިޔަބައިމީހުންގެ ކުށްތައް ފުއްސަވައި، އެތާނގެދަށުން ފެންކޯރުތައް ހިނގަހިނގާހުންނަ ސުވަރުގެތަކަށް ތިޔަބައިމީހުން ވައްދަވައިފާނެތެވެ. ނަބިއްޔާއާއި، އެކަލޭގެފާނުގެ އަރިހުގައިވާ އީމާން ވިމީހުން، ﷲ ނިކަމެތިނުކުރައްވާނެ ދުވަހުގައެވެ. އެއުރެންގެ ނޫރު، އެއުރެންގެ ކުރިމަތިންނާއި، އެއުރެންގެ ކަނާތްފަރާތުން ހިނގަހިނގާ ހުންނާނެތެވެ. އެއުރެން ބުނާނެތެވެ. އަޅަމެންގެ ވެރިރަސްކަލާކޮ! އަޅަމެންގެ ނޫރު އަޅަމެންނަށް ފުރިހަމަކޮށްދެއްވާނދޭވެ! އަދި އަޅަމެންނަށް ފާފަފުއްސަވާނދޭވެ! ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެއީ، ކޮންމެ ކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","يا أيها النبي جاهد الكفار والمنافقين واغلظ عليهم ومأواهم جهنم وبئس المصير","އޭ ނަބިއްޔާއެވެ! ކާފިރްނާއި، މުނާފިގުންނާ ދެކޮޅަށް ކަލޭގެފާނު ޖިހާދުކުރައްވާށެވެ! އަދި އެއުރެންގެ މައްޗަށް ހަރުކަށިވެވަޑައިގަންނަވާށެވެ! އެއުރެން ތިބެނިވި ތަނަކީ ނަރަކައެވެ. އަދި އެއީ ހާދަހާ ނުބައިވެގެންވާ ނިމިދިޔުމެކެވެ.","",""],["","","","ضرب الله مثلا للذين كفروا امرأت نوح وامرأت لوط كانتا تحت عبدين من عبادنا صالحين فخانتاهما فلم يغنيا عنهما من الله شيئا وقيل ادخلا النار مع الداخلين","ނޫޙުގެފާނުގެ އަނބިކަނބަލުންނާއި، ލޫޠުގެފާނުގެ އަނބިކަނބަލުންގެ ވާހަކައިން، ކާފިރު ވިމީހުންނަށް ﷲ، މިސާލެއް ޖެއްސެވިއެވެ. އެ ދެބޭކަނބަލުން ތިއްބެވީ ތިމަންރަސްކަލާނގެ ސާލިހު އަޅުންގެ ތެރެއިން ދެ އަޅެއްގެ އަމުރުގެ ދަށުގައެވެ. ފަހެ، އެ ދެބޭކަނބަލުން، އެ ދެބޭކަލުންނަށް ޚިޔާނަތް ތެރިވިއެވެ. ފަހެ، ﷲގެ ހަޒުރަތުން އެއްވެސްކަމެއް އެ ދެބޭކަނބަލުންނަށްޓަކައި، އެ ދެބޭކަލުންނަކަށް ފުއްދައެއް ނުދެއްވުނެވެ. އަދި އެ ދެބޭކަނބަލުންނަށް އަންގަވާނެތެވެ. (ނަރަކައަށް) ވަންނަމީހުނާއެކު، ތިޔަ ދެމީހުންވެސް ނަރަކަޔަށް ވަންނާށެވެ!","",""],["","","","وضرب الله مثلا للذين آمنوا امرأت فرعون إذ قالت رب ابن لي عندك بيتا في الجنة ونجني من فرعون وعمله ونجني من القوم الظالمين","އަދި ފިރްޢައުނުގެ އަނބިކަނބަލުންގެ ވާހަކައިން، އީމާންވި މީހުންނަށް ﷲ، މިސާލެއް ޖެއްސެވިއެވެ. (އެއީ) އެކަމަނާ ވިދާޅުވިހިނދުގައެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ތިމަންއަޅާޔަށް އިބަރަސްކަލާނގެ ހަޒުރަތުގައި، ސުވަރުގޭގައި ގެއެއް ބިނާކޮށްދެއްވާނދޭވެ! އަދި ފިރްޢައުނާއި، އޭނާގެ (ނުބައި) ޢަމަލުން މިއަޅާ ސަލާމަތްކޮށްދެއްވާނދޭވެ! އަދި އަނިޔާވެރި ގައުމުގެމީހުންގެ ކިބައިންވެސް މިއަޅާ ސަލާމަތްކޮށްދެއްވާނދޭވެ!","",""],["","","","ومريم ابنت عمران التي أحصنت فرجها فنفخنا فيه من روحنا وصدقت بكلمات ربها وكتبه وكانت من القانتين","އަދި ޢިމްރާންގެ ދަރިކަނބަލުން މަރިޔަމްގެފާނުގެ މިސާލު ވެސްމެއެވެ. އެކަމަނާއީ، އެކަމަނާގެ ފަރުޖު ރައްކާތެރިކުރެއްވި ކަމަނާއެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ ރޫޙުފުޅުން އެކަމަނާގެ ގައިކޮޅަށް ފުމެލެއްވީމެވެ. އަދި އެކަމަނާގެ ވެރިރަސްކަލާނގެ ކަލިމަ ފުޅުތަކާއި، އެކަލާނގެ (ބާވައިލެއްވި) ފޮތްތައް އެކަމަނާ ތެދުކުރެއްވިއެވެ. އަދި އެކަމަނާ ވަނީ، ކިޔަމަންތެރި އަޅުވެރިންގެ ތެރެއިންނެވެ.","",""],["","","","بسم الله الرحمن الرحيم تبارك الذي بيده الملك وهو على كل شيء قدير","އެކަލާނގެ އަތްޕުޅުގައި ވެރިކަންވާ ރަސްކަލާނގެ މަތިވެރިވެ ވޮޑިގެންފިއެވެ. އަދި އެކަލާނގެއީ، ކޮންމެކަމެއްގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","الذي خلق الموت والحياة ليبلوكم أيكم أحسن عملا وهو العزيز الغفور","އެކަލާނގެއީ ތިޔަބައިމީހުންކުރެ އެންމެ ޢަމަލު ރަނގަޅީ ކާކުތޯ އިމްތިހާނުކުރެއްވުމަށްޓަކައި، މަރުވުމާއި، ދިރިހުރުން، އުފެއްދެވި ރަސްކަލާނގެއެވެ. އަދި އެކަލާނގެއީ، ޢަޒީޒުވަންތަ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަސްކަލާނގެއެވެ.","",""],["","","","الذي خلق سبع سماوات طباقا ما ترى في خلق الرحمن من تفاوت فارجع البصر هل ترى من فطور","އެކަލާނގެއީ، މަތިމައްޗަށް ހަތްއުޑު ހެއްދެވި ރަސްކަލާނގެއެވެ. ރަޙްމާންވަންތަ ރަސްކަލާނގެ (އެތަކެތި) ހެއްދެވުމުގައި އެއްވެސްކަހަލަ އުނިކަމެއް ތިބާޔަކަށް ނުފެންނާނެތެވެ. ފަހެ، ތަކުރާރު ކޮށް ނަޡަރު ހިންގައި ބަލާށެވެ! އެއްވެސްކަހަލަ ޚަލަލެއް ތިބާޔަށް ފެނޭހެއްޔެވެ؟","",""],["","","","ثم ارجع البصر كرتين ينقلب إليك البصر خاسئا وهو حسير","ދެންވެސް ތަކުރާރު ކޮށް ދެފަހަރަށް ނަޡަރު ހިންގައި ބަލާށެވެ! އޭރުން ދެރަވެ، ނިކަމެތިވެގެންވާ ޙާލުގައި (ތިބާގެ) ނަޡަރު އެނބުރި ތިބާގެގާތަށް އަންނަހުށްޓެވެ.","",""],["","","","ولقد زينا السماء الدنيا بمصابيح وجعلناها رجوما للشياطين وأعتدنا لهم عذاب السعير","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ބައްތިތަކަކުން އެންމެކައިރި އުޑު ޒީނަތް ތެރިކުރެއްވީމެވެ. އަދި ޝައިތާނުންނާ ދިމާޔަށް އުއްކަވާ ގިނިހިލަތަކެއް ކަމުގައި އެތަކެތި ލެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އެ ޝައިތާނުންނަށް ނަރަކައިގެ އަޒާބުތައްޔާރުކުރެއްވީމެވެ.","",""],["","","","وللذين كفروا بربهم عذاب جهنم وبئس المصير","އަދި އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ކާފިރުވި މީހުންނަށް ނަރަކައިގެ އަޒާބު ހުށްޓެވެ. އަދި އެއީ ހާދަހާ ނުބައިވެގެންވާ ނިމިދިޔުމެކެވެ.","",""],["","","","إذا ألقوا فيها سمعوا لها شهيقا وهي تفور","އެ ނަރަކައިގެ ތެރެޔަށް އެއުރެން އެއްލައިލައްވާހިނދު، އެ ނަރަކަ ކެކިގަންނަ ޙާލުގައި، އެތެރެޔަށް ދަމައިލާއަޑު އެއުރެންނަށް އިވޭނެތެވެ.","",""],["","","","تكاد تميز من الغيظ كلما ألقي فيها فوج سألهم خزنتها ألم يأتكم نذير","އެ ނަރަކަ އަންނަރުޅިން ކުދިކުދިވެދާން ކައިރިވެދެއެވެ. (ކާފިރުންގެ) ފައުޖެއް އެ ނަރަކަޔަށް އެއްލަވާ ކޮންމެފަހަރަކު، އެތާނގެ ބަނޑޭރިން އެއުރެންނާ ސުވާލުކުރައްވާނެތެވެ. އިންޒާރުކުރައްވާ ރަސޫލަކު ތިޔަބައިމީހުންގެގާތަށް ވަޑައެއް ނުގަންނަވާހެއްޔެވެ؟","",""],["","","","قالوا بلى قد جاءنا نذير فكذبنا وقلنا ما نزل الله من شيء إن أنتم إلا في ضلال كبير","އެއުރެން ދަންނަވާނެތެވެ. އެހެންނަކުންނޫނެވެ. ހަމަކަށަވަރުން، ތިމަންމެންގެގާތަށް އިންޒާރުކުރައްވާ ރަސޫލަކު ވަޑައިގަތެވެ. ދެން ތިމަންމެން ދޮގުކުރީމުއެވެ. އަދި ތިމަންމެން ބުނީމުއެވެ. ﷲ، އެއްވެސް އެއްޗެއް ބާވައެއް ނުލައްވަތެވެ. ތިޔަބޭކަލުން ބޮޑުވެގެންވާ ފުރެދުމެއްގައި މެނުވީ ނުވަމުއެވެ.","",""],["","","","وقالوا لو كنا نسمع أو نعقل ما كنا في أصحاب السعير","އަދި އެއުރެން ބުނާނެތެވެ. ތިމަންމެން އަޑުއަހާކަމުގައިވީނަމަ، ނުވަތަ ވިސްނައި ފިކުރުކުރާކަމުގައިވީނަމަ، ނަރަކައިގެ އަހުލުވެރިންގެ ތެރެޔަކު ތިމަންމެން ނުވީހެވެ.","",""],["","","","فاعترفوا بذنبهم فسحقا لأصحاب السعير","ފަހެ، އެއުރެން، އެއުރެންގެ ފާފަތަކަށް އިޢުތިރާފް ވާނެތެވެ. ފަހެ، ނަރަކައިގެ އަހުލުވެރިންނަށް ރަހުމަތުން ދުރުކުރެއްވުން ހުށްޓެވެ.","",""],["","","","إن الذين يخشون ربهم بالغيب لهم مغفرة وأجر كبير","ހަމަކަށަވަރުން، ނުފެންނަތާނގައި އެއުރެންގެ ވެރިރަސްކަލާނގެއަށް ބިރުވެތިވާމީހުން (ދަންނާށެވެ!) ފާފަފުއްސެވުމާއި، ބޮޑުވެގެންވާ ދަރުމަ، އެމީހުންނަށް ހުށްޓެވެ.","",""],["","","","وأسروا قولكم أو اجهروا به إنه عليم بذات الصدور","ތިޔަބައިމީހުން ބުނާއެއްޗެއް ސިއްރުކުރާށެވެ! ނުވަތަ އެ ފާޅުކުރާށެވެ! ހަމަކަށަވަރުން، އެކަލާނގެއީ، ހިތްތަކުގައި ވާހާކަމެއް، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","ألا يعلم من خلق وهو اللطيف الخبير","(ހުރިހާ ތަކެއްޗެއް) ހެއްދެވި ރަސްކަލާނގެ (އެތަކެތި) ދެނެވޮޑިގެން ނުވާނޭހެއްޔެވެ؟ އަދި އެކަލާނގެއީ، އޯގާވަންތަކަންބޮޑު، މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","هو الذي جعل لكم الأرض ذلولا فامشوا في مناكبها وكلوا من رزقه وإليه النشور","އެކަލާނގެއީ، ތިޔަބައިމީހުންނަށްޓަކައި، ފަސޭހަތަނެއް ކަމުގައި ބިންގަނޑު ލެއްވި ރަސްކަލާނގެއެވެ. ފަހެ، އެތާނގެ ކަންކޮޅުތަކުގައި ތިޔަބައިމީހުން ހިނގައި ދަތުރުކުރާށެވެ! އަދި އެކަލާނގެ ދެއްވި ރިޒްގުން ކާށެވެ! އަދި އަލުން ދިރުއްވައި ފޮނުއްވުންވަނީ، އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","أأمنتم من في السماء أن يخسف بكم الأرض فإذا هي تمور","އުޑުގައިވާ ކަލާނގެ (އެބަހީ: މަތިވެރިވެގެންވާ ރަސްކަލާނގެ) ތިޔަބައިމީހުންނާއިގެން ބިންގަނޑު ގަންބަވައިގެންފާނެ ކަމާމެދު (ބިރެއްނެތި) އަމާންކަމުގައި ތިޔަބައިމީހުން ތިބީހެއްޔެވެ؟ ފަހެ، އެހާރުން، ބިންގަނޑު ތެޅިފޮޅިގަންނާނެތެވެ.","",""],["","","","أم أمنتم من في السماء أن يرسل عليكم حاصبا فستعلمون كيف نذير","ނުވަތަ އުޑުގައިވާ ކަލާނގެ (އެބަހީ: މަތިވެރިވެގެންވާ ރަސްކަލާނގެ) ތިޔަބައިމީހުންގެ މައްޗަށް ހިލައިގެ ވާރޭ ފޮނުއްވައިފާނޭކަމާމެދު (ބިރެއްނެތި) އަމާންކަމުގައި ތިޔަބައިމީހުން ތިބީހެއްޔެވެ؟ ފަހެ، ތިމަންރަސްކަލާނގެ އިންޒާރުކުރެއްވުންވަނީ، ކޮންފަދައަކުންކަން ނިކަންހުރެ ތިޔަބައިމީހުންނަށް އެނގޭނެތެވެ.","",""],["","","","ولقد كذب الذين من قبلهم فكيف كان نكير","ހަމަކަށަވަރުން، އެއުރެންގެކުރިން އުޅުނުމީހުންވެސް (ރަސޫލުން) ދޮގުކުރޫއެވެ. ފަހެ، ތިމަންރަސްކަލާނގެ އުގޫބާތް ދެއްވުންވީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","أولم يروا إلى الطير فوقهم صافات ويقبضن ما يمسكهن إلا الرحمن إنه بكل شيء بصير","ފިޔަތައް ދަމާލައިގެންނާއި، އަދި ފިޔަތައް ލައްޕާލައިގެން، އެއުރެންގެ މަތީގައި (އުދުހި) އުޅޭ ދޫނިތަކަށް އެއުރެން ނުބަލަނީ ހެއްޔެވެ؟ ރަޙްމާންވަންތަ ރަސްކަލާނގެ މެނުވީ، އެތަކެތި (ވެއްޓުނަނުދީ) ނުހިފަހައްޓަވަތެވެ. ހަމަކަށަވަރުން، އެކަލާނގެއީ، ހުރިހާއެއްޗެއް މޮޅަށް ބައްލަވާވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","أمن هذا الذي هو جند لكم ينصركم من دون الرحمن إن الكافرون إلا في غرور","ނުވަތަ ރަޙްމާންވަންތަ ރަސްކަލާނގެ ފިޔަވައި ތިޔަބައިމީހުންނަށް ނަސްރު ދޭނޭ ލަޝްކަރެއް ކަމުގައިވަނީ ކޮންބަޔެއްހެއްޔެވެ؟ ހެއްލުމެއްގެތެރޭގައި މެނުވީ ކާފިރުންނުވެއެވެ.","",""],["","","","أمن هذا الذي يرزقكم إن أمسك رزقه بل لجوا في عتو ونفور","ނުވަތަ އެކަލާނގެ ރިޒްގު ދެއްވުން ހުއްޓަވައިފިނަމަ، ތިޔަބައިމީހުންނަށް ރިޒްގު ދޭނޭ މީހަކީ އެއީކާކުހެއްޔެވެ؟ އަދި ކިއެއްތަ! އެއުރެންވަނީ ކިބުރުވެރިކަމާއި ހައްގުން އެއްކިބާވުމެއްގައެވެ.","",""],["","","","أفمن يمشي مكبا على وجهه أهدى أمن يمشي سويا على صراط مستقيم","ފަހެ، ތެދުމަގު ލިބުންބޮޑީ، މޫނުވަތަށް ވެއްޓެމުން ހިނގައިދާ މީހާހެއްޔެވެ؟ ނުވަތަ ސީދާވެގެންވާ ތެދުމަގެއްގައި، ތެދަށް ހިނގައިދާ މީހާ ހެއްޔެވެ؟","",""],["","","","قل هو الذي أنشأكم وجعل لكم السمع والأبصار والأفئدة قليلا ما تشكرون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަލާނގެއީ، ތިޔަބައިމީހުން އުފައްދަވައި، ތިޔަބައިމީހުންނަށް އިވުމާއި، ފެނުމާއި، ހިތްތައް، ލެއްވި ރަސްކަލާނގެއެވެ. ތިޔަބައިމީހުން ޝުކުރުކުރަނީ ވަރަށްވެސް މަދުންނެވެ.","",""],["","","","قل هو الذي ذرأكم في الأرض وإليه تحشرون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެކަލާނގެއީ ތިޔަބައިމީހުން ބިމުގައި އުފެއްދެވި ރަސްކަލާނގެއެވެ. އަދި (ގިޔާމަތް ދުވަހުން) ތިޔަބައިމީހުން އެއްކުރައްވާހުށީ އެކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","ويقولون متى هذا الوعد إن كنتم صادقين","އެއުރެން ބުނެތެވެ. ތިޔަބައިމީހުންނީ، ތެދުބުނާ ބަޔަކުކަމުގައިވާނަމަ، ތިޔަ (ބުނާ އަޒާބުގެ) ވައުދު އަންނާނީ ކޮންއިރަކުން ހެއްޔެވެ؟","",""],["","","","قل إنما العلم عند الله وإنما أنا نذير مبين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! (އެކަން) ދެނެވޮޑިގަތުން ވާކަންކަށަވަރީ، ﷲގެ ހަޒުރަތު ގައެވެ. އަދި ތިމަންކަލޭގެފާނު ވާކަންކަށަވަރީ، ބަޔާންވެގެންހުރި، އިންޒާރުކުރައްވާ ބޭކަލަކު ކަމުގައެވެ.","",""],["","","","فلما رأوه زلفة سيئت وجوه الذين كفروا وقيل هذا الذي كنتم به تدعون","ފަހެ، އެއުރެންނަށް އެ ވައުދު، ކައިރިން ފެނިއްޖެހިނދު، ކާފިރު ވިމީހުންގެ މޫނުތަކަށް ހިތާމަވެރިކަން ލިބިގެންދާނެތެވެ. އަދި އަންގަވާނެތެވެ. މިއީ ތިޔަބައިމީހުން އެދިގޮވާކަމުގައިވި ކަންތަކެވެ.","",""],["","","","قل أرأيتم إن أهلكني الله ومن معي أو رحمنا فمن يجير الكافرين من عذاب أليم","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ނިކަން ޚަބަރު ދީބަލާށެވެ! ﷲ ތިމަންކަލޭގެފާނާއި، ތިމަންކަލޭގެފާނާ އެކުގައިވާ ބަޔަކު ހަލާކުކުރެއްވި ނަމަވެސް، ނުވަތަ ތިމަންމެންނަށް ރަހުމަތް ލެއްވިނަމަވެސް، ފަހެ، ވޭންދެނިވި އަޒާބުން، ކާފިރުން ސަލާމަތްކޮށްދޭނީ ކާކުހެއްޔެވެ؟","",""],["","","","قل هو الرحمن آمنا به وعليه توكلنا فستعلمون من هو في ضلال مبين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އެއީ ރަޙްމާންވަންތަ ރަސްކަލާނގެއެވެ. ތިމަންމެން އެކަލާނގެއަށް އީމާން ވެއްޖައީމުއެވެ. އަދި ހަމައެކަނި އެކަލާނގެއަށް ތިމަންމެން ވަކީލު ކޮށްފީމުއެވެ. ފަހެ، ބަޔާންވެގެންވާ ފުރެދުމެއްގައިވަނީ ކާކުކަން، ނިކަންހުރެ ތިޔަބައިމީހުންނަށް އެނގޭނެތެވެ.","",""],["","","","قل أرأيتم إن أصبح ماؤكم غورا فمن يأتيكم بماء معين","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުން ނިކަން ޚަބަރު ދީބަލާށެވެ! ތިޔަބައިމީހުންގެ (ބޭނުންކުރާ) ފެން އަޑިޔަށް ހިނދިއްޖެނަމަ، ހިނގަހިނގާ ހުންނަ ފެނެއް ތިޔަބައިމީހުންނަށް ގެނެސްދޭހުށީ ފަހެ ކާކުހެއްޔެވެ؟","",""],["","","","بسم الله الرحمن الرحيم ن والقلم وما يسطرون","ن (މި އަކުރުގެ މުރާދު ދެނެވޮޑިގެންވަނީ ﷲއެވެ.) ގަލަމާއި (އެ ގަލަމުން) އެއުރެން ލިޔާ ތަކެތި ގަންދެއްވައި ވަހީކުރައްވަމެވެ.","",""],["","","","ما أنت بنعمة ربك بمجنون","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ނިއުމަތުން ކަލޭގެފާނީ މޮޔަޔަކު ކަމުގައި ވެވަޑައިނުގަންނަވަމުއެވެ.","",""],["","","","وإن لك لأجرا غير ممنون","އަދި ހަމަކަށަވަރުން، ނިމުމެއްނުވާ ދަރުމައެއް ކަލޭގެފާނަށް ހުށްޓެވެ.","",""],["","","","وإنك لعلى خلق عظيم","އަދި ހަމަކަށަވަރުން، ކަލޭގެފާނު ވަނީ މާތްވެގެންވާ ޚަލްގު ފުޅެއްގެ މަތީގައިކަން ކަށަވަރެވެ.","",""],["","","","فستبصر ويبصرون","މޮޔަވެފައިވަނީ ތިޔަބައިމީހުންކުރެ ކާކުކަން ފަހެ، ކަލޭގެފާނަށް ފެނިވަޑައިގަންނަވާނެތެވެ. އަދި އެއުރެންނަށްވެސް ފެންނާނެތެވެ.","",""],["","","","بأييكم المفتون","މޮޔަވެފައިވަނީ ތިޔަބައިމީހުންކުރެ ކާކުކަން ފަހެ، ކަލޭގެފާނަށް ފެނިވަޑައިގަންނަވާނެތެވެ. އަދި އެއުރެންނަށްވެސް ފެންނާނެތެވެ.","",""],["","","","إن ربك هو أعلم بمن ضل عن سبيله وهو أعلم بالمهتدين","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެކަލާނގެ މަގުން އެއްކިބާވެގެންވާ މީހުން މޮޅަށް ދެނެވޮޑިގެންވެތެވެ. އަދި ތެދުމަގު ލިބިގެންވާ މީހުންވެސް މޮޅަށް ދެނެވޮޑިގެންވަނީ އެކަލާނގެއެވެ.","",""],["","","","فلا تطع المكذبين","ފަހެ، ދޮގުކުރާ މީހުންނަށް ކަލޭގެފާނު ކިޔަމަންވެވަޑައިނުގަންނަވާށެވެ!","",""],["","","","ودوا لو تدهن فيدهنون","ކަލޭގެފާނު އެއުރެންނަށް ދުލެއް ދެއްވާނެނަމަ، ކޮންފަދަހޭ ހިތައި، އެކަމަށް އެއުރެން އެދުނޫއެވެ. އެއީ އެއުރެންވެސް ކަލޭގެފާނަށް ދުލެއް ދިނުމަށްޓަކައެވެ.","",""],["","","","ولا تطع كل حلاف مهين","އަދި ގިނަގިނައިން ހުވާކޮށްހަދާ، އިހާނަތްތެރިކަން ލިބިގެންވާ ކޮންމެ މީހަކަށް ކަލޭގެފާނު ކިޔަމަންވެވަޑައިނުގަންނަވާށެވެ!","",""],["","","","هماز مشاء بنميم","(އެއީ) ޣީބަ ބުނެހަދާ، ދެބައޮޑުވަމުން ހިނގައިއުޅޭ މީހާއެވެ.","",""],["","","","مناع للخير معتد أثيم","ހެޔޮކަންތައް މަނާކުރުންގިނަ، ހައްދުފަހަނަޅައިފައިވާ، ފާފަކުރުންގިނަ މީހާއެވެ.","",""],["","","","عتل بعد ذلك زنيم","ހިތްހަރު މީހާއެވެ. އެހުރިހާ ކަމަކަށްފަހުގައި، ބަފާ ނުކަށަވަރު ދަރިޔެކެވެ.","",""],["","","","أن كان ذا مال وبنين","އޭނާއީ މުދާވެރި، އަދި ދަރިންތިބި މީހަކަށްވީތީއެވެ.","",""],["","","","إذا تتلى عليه آياتنا قال أساطير الأولين","ތިމަންރަސްކަލާނގެ އާޔަތްތައް އޭނާޔަށް ކިޔައިދެއްވާހިނދު، އޭނާ ބުނެތެވެ. (ތިޔައީ) އެވޭލާ މީހުން ދައްކައިއުޅުނު ފުލޯކު ވާހަކަތަކެވެ.","",""],["","","","سنسمه على الخرطوم","ނިކަންހުރެ އޭނާގެ ނޯށްމަތީގައި ތިމަންރަސްކަލާނގެ ފާހަގަލައްވާހުށީމެވެ.","",""],["","","","إنا بلوناهم كما بلونا أصحاب الجنة إذ أقسموا ليصرمنها مصبحين","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެން އިމްތިހާނުކުރެއްވީމެވެ. ތިމަންރަސްކަލާނގެ ބަގީޗާގެ އަހުލުވެރިން އިމްތިހާނުކުރެއްވި ފަދައިންނެވެ. އެއުރެން ހެނދުނު ހެނދުނާ މޭވާ ބިންނާނޭކަމަށް ހުވާކުރިހިނދެވެ.","",""],["","","","ولا يستثنون","އަދި އެއުރެން އިސްތިޘްނާއެއް ނުކުރެތެވެ. (އެބަހީ: إن شاء ﷲ އޭ ނުބުނެތެވެ.)","",""],["","","","فطاف عليها طائف من ربك وهم نائمون","ފަހެ (އެރޭ) އެއުރެން ނިދާފައިތިއްބައި، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ބަލާއެއް، އެ ބަގީޗާގެ މައްޗަށް އައެވެ.","",""],["","","","فأصبحت كالصريم","ދެން އެ ބަގީޗާގެ ގަސްތައް އަނދައި، ކަޅުއަނދިރި ރޭގަނޑެއް ފަދައިންވިއެވެ.","",""],["","","","فتنادوا مصبحين","ފަހެ، އެއުރެން ހެނދުނު އެކަކު އަނެކަކަށް ގޮވައިހެދޫއެވެ.","",""],["","","","أن اغدوا على حرثكم إن كنتم صارمين","ތިޔަބައިމީހުން އިންދި ތަކެތީގެ މޭވާ ބިންނަން ތިބިނަމަ، ދަނޑުތަކަށް ހެނދުނާ އަވަހަށް ހިނގާށެވެ!","",""],["","","","فانطلقوا وهم يتخافتون","ފަހެ، އެއުރެން ސިއްރުސިއްރުން ވާހަކަދައްކަމުން (އެތަނަށް) ދިޔައޫއެވެ.","",""],["","","","أن لا يدخلنها اليوم عليكم مسكين","މިއަދު ތިޔަބައިމީހުންގެ ގާތަށް އެ ބަގީޗާއަށް އެއްވެސް މިސްކީނަކު ވަނަދީގެނެއް ނުވާނެތެވެ.","",""],["","","","وغدوا على حرد قادرين","އަދި ފަގީރުންނަށް ނުދިނުމަށް ކުޅަދާނަކަން ލިބިގެންވާކަމަށްހީކޮށް، އެކަމުގެ ގަސްދުގައި ހެނދުނާ އެއުރެން ދިޔައޫއެވެ.","",""],["","","","فلما رأوها قالوا إنا لضالون","ފަހެ، އެއުރެންނަށް އެ ބަގީޗާގެ ގަސްތަކަށް ޖެހިފައިވާ ޙާލު ފެނުނުހިނދު އެއުރެން ބުނޫއެވެ. ހަމަކަށަވަރުން، ތިމަންމެންނީ، މަގުއޮޅިގެންވާ ބަޔަކީމުއެވެ.","",""],["","","","بل نحن محرومون","އަދި ކިއެއްތަ! ތިމަންމެންނީ (އެ ބަގީޗާގެ މޭވާތަކުން) މަޙްރޫމު ވެގެންވާ ބަޔަކީމުއެވެ.","",""],["","","","قال أوسطهم ألم أقل لكم لولا تسبحون","އެއުރެންކުރެ އެންމެ ބުއްދިވެރި މީހާ ބުންޏެވެ. ތިޔަބައިމީހުން (ﷲ ހަނދުމަކޮށް) ތަސްބީހަ ނުކިޔަނީ ކީއްވެހޭ، ތިމަން ތިޔަބައިމީހުންނަށް ނުބުނަން ހެއްޔެވެ؟","",""],["","","","قالوا سبحان ربنا إنا كنا ظالمين","އެއުރެން ބުނޫއެވެ. ތިމަންމެންގެ ވެރިރަސްކަލާނގެ، ހުސްތާހިރު ވަންތަކަމާއެވެ! ހަމަކަށަވަރުން، ތިމަންމެންވީ އަނިޔާވެރިންކަމުގައެވެ.","",""],["","","","فأقبل بعضهم على بعض يتلاومون","ފަހެ، އެއުރެން އެއްބަޔަކު އަނެއްބަޔަކާ ކުރިމަތިލައި އެއްބަޔަކު އަނެއްބަޔަކަށް މަލާމާތްކުރެތެވެ.","",""],["","","","قالوا يا ويلنا إنا كنا طاغين","އެއުރެން ބުނޫއެވެ. އޭ ތިމަންމެންނަށްހުރި ހަލާކެއްގެ ބޮޑުކަމާއެވެ! ހަމަކަށަވަރުން، ތިމަންމެންވީ (ފުރެދުމުގައި) ހައްދުފަހަނަޅައިފައިވާ ބަޔަކުކަމުގައެވެ.","",""],["","","","عسى ربنا أن يبدلنا خيرا منها إنا إلى ربنا راغبون","އަޅަމެންގެ ވެރިރަސްކަލާނގެ އޭގެ ބަދަލުގައި އެއަށްވުރެ ހެޔޮވެގެންވާ ނިއުމަތެއް އަޅަމެންނަށް ދެއްވައިފާށިއެވެ! ހަމަކަށަވަރުން، ތިމަންމެންވަނީ ތިމަންމެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް އެދިއެދިތިބޭ ބަޔަކު ކަމުގައެވެ.","",""],["","","","كذلك العذاب ولعذاب الآخرة أكبر لو كانوا يعلمون","އަޒާބު ހުރީ އެފަދައިންނެވެ. އަދި އާޚިރަތްގެ އަޒާބު (އެއަށްވުރެ) މާބޮޑުކަން ކަށަވަރެވެ. އެކަން އެއުރެންނަށް އެނގޭނެނަމައެވެ.","",""],["","","","إن للمتقين عند ربهم جنات النعيم","ހަމަކަށަވަރުން، ތަގުވާވެރިންނަށް އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ނިއުމަތްގެ ސުވަރުގެތައްވެއެވެ.","",""],["","","","أفنجعل المسلمين كالمجرمين","ފަހެ، ތިމަންރަސްކަލާނގެ (ކިޔަމަންތެރި) މުސްލިމުން (ކާފިރުވި) ކުށްވެރިންނާ އެއްފަދަ ކުރައްވާނޭ ހެއްޔެވެ؟","",""],["","","","ما لكم كيف تحكمون","ތިޔަބައިމީހުންނަށް ތިޔަތިބީ ކީއްވެފައިހެއްޔެވެ؟ ތިޔަބައިމީހުން ތިޔަ ހުކުމްކުރަނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","أم لكم كتاب فيه تدرسون","އަދި ކިއެއްތަ! ތިޔަބައިމީހުން އެފޮތުން ކިޔަވާނޭ ފޮތެއް ތިޔަބައިމީހުންނަށް ވޭހެއްޔެވެ؟","",""],["","","","إن لكم فيه لما تخيرون","ހަމަކަށަވަރުން، އެފޮތުގައި ތިޔަބައިމީހުން އިޚްތިޔާރުކުރަން ބޭނުން ގޮތްތައް ވޭހެއްޔެވެ؟","",""],["","","","أم لكم أيمان علينا بالغة إلى يوم القيامة إن لكم لما تحكمون","ނުވަތަ ގިޔާމަތް ދުވަހާ ޖެހެންދެން ކަށަވަރުވެ، ދެމިއޮންނަ އަހުދު ތަކެއް ތިމަންރަސްކަލާނގެ ހަޒުރަތުން ތިޔަބައިމީހުންނަށް ވަނީހެއްޔެވެ؟ ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ހުކުމްކުރާ ގޮތްތައްހުރީ، ހަމަ ތިޔަބައިމީހުންނަށެވެ.","",""],["","","","سلهم أيهم بذلك زعيم","ކަލޭގެފާނު އެއުރެންނާ ސުވާލުކުރައްވައި ބައްލަވާށެވެ! އެއުރެންކުރެ އެކަމަށް ޖާމިނުވާހުށީ ކާކުހެއްޔެވެ؟","",""],["","","","أم لهم شركاء فليأتوا بشركائهم إن كانوا صادقين","ނުވަތަ އެއުރެންނަށް ބައިވެރިންތަކެއް ވަނީހެއްޔެވެ؟ އެއުރެންނީ ތެދުވެރިންކަމުގައިވާނަމަ، ފަހެ، އެއުރެންގެ ބައިވެރިން ގޮވައިގެން އެއުރެން އަންނަހުށިކަމެވެ!","",""],["","","","يوم يكشف عن ساق ويدعون إلى السجود فلا يستطيعون","ކަށިމަތިފުޅު ހާމަވާ ދުވަސް ހަނދުމަކުރާށެވެ! (އެދުވަހުން) އެއުރެންނަށް ސަޖިދަކުރުމަށް ގޮވައިލައްވާނެތެވެ. ފަހެ، އެއުރެންނަކަށް (އެކަމަކަށް) ކުޅަދާނަވެގެނެއްނުވާނެތެވެ.","",""],["","","","خاشعة أبصارهم ترهقهم ذلة وقد كانوا يدعون إلى السجود وهم سالمون","(އެއުރެން ތިބޭހުށީ) އެއުރެންގެ ލޯތައް ތިރިވެ، އެއުރެންގެ މައްޗަށް ނިކަމެތިކަން ވެރިވެފައެވެ. ހަމަކަށަވަރުން، އެއުރެން ސަލާމަތުން ތިބިއިރު، ސަޖިދަކުރުމަށް ގޮވައިލައްވާ ކަމުގައިވިއެވެ.","",""],["","","","فذرني ومن يكذب بهذا الحديث سنستدرجهم من حيث لا يعلمون","ފަހެ، މި ގުރްއާން ދޮގުކުރާމީހުން، ކަލޭގެފާނު ތިމަންރަސްކަލާނގެއަށް ދޫކޮށްލައްވާށެވެ! އެއުރެންނަށް ނޭނގޭނޭގޮތުން (އަޒާބުގެ ތެރެޔަށް) ތިމަންރަސްކަލާނގެ، އެއުރެން ނިކަންހުރެ ގެންދަވާހުށީމެވެ.","",""],["","","","وأملي لهم إن كيدي متين","އަދި އެއުރެންނަށް ތިމަންރަސްކަލާނގެ ލަސްކުރައްވަމެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ރޭއްވެވުން ގަދަފަދަވެގެންވެއެވެ.","",""],["","","","أم تسألهم أجرا فهم من مغرم مثقلون","އަދި ކިއެއްތަ! އެއުރެންގެ ކިބައިން އުޖޫރައަކަށް ކަލޭގެފާނު އެދިވަޑައިގަންނަވަނީތޯއެވެ؟ ފަހެ، އެއުރެން އެ އުޖޫރަ ދޭންޖެހުމުގެ ސަބަބުން އެއުރެންނަށް ބުރަކަމެއް ލިބެނީތޯއެވެ؟","",""],["","","","أم عندهم الغيب فهم يكتبون","ނުވަތަ އެއުރެން (އެއިން) ލިޔުމަށް އެއުރެންގެ ގާތުގައި ޣައިބުގެ އިލްމު ވަނީހެއްޔެވެ؟","",""],["","","","فاصبر لحكم ربك ولا تكن كصاحب الحوت إذ نادى وهو مكظوم","ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހުކުމް ފުޅަށް ކަލޭގެފާނު ކެތްކުރައްވާށެވެ! އަދި ބޮޑުމަހުގެ އެކުވެރިޔާ (އެބަހީ: ޔޫނުސްގެފާނު) ފަދައިން ކަލޭގެފާނު ވެވަޑައިނުގަންނަވާށެވެ! އެކަލޭގެފާނު، ބޮޑުވެގެންވާ ހިތާމައިގައިވާ ޙާލު، ދުއާކުރެއްވި ހިނދުގައެވެ.","",""],["","","","لولا أن تداركه نعمة من ربه لنبذ بالعراء وهو مذموم","އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ފޮނުއްވި ނިއުމަތެއް، އެކަލޭގެފާނާ ހަމަޔަށް ވާޞިލު ނުވިނަމަ، އެކަލޭގެފާނަށް މަލާމާތްލިބިގެންވާ ޙާލު (މަހުގެ ބަނޑުން، ކަނޑުގެ) އައްސޭރިޔަށް އެކަލޭގެފާނު އެއްލައިލެއްވީހެވެ.","",""],["","","","فاجتباه ربه فجعله من الصالحين","ދެން އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، އެކަލޭގެފާނު ޚިޔާރުކުރެއްވިއެވެ. އަދި ސާލިހު އަޅުންގެ ތެރެއިން އެކަލޭގެފާނު ލެއްވިއެވެ.","",""],["","","","وإن يكاد الذين كفروا ليزلقونك بأبصارهم لما سمعوا الذكر ويقولون إنه لمجنون","ކާފިރުވި މީހުން ގުރްއާންގެ އަޑު އެހިހިނދު، އެއުރެންގެ ބެލުންތަކުން ކަލޭގެފާނު ކައްސުވާލައި، ވައްޓައިލުމާ ގާތްކުރެތެވެ. އަދި އެއުރެން ބުނެތެވެ. ހަމަކަށަވަރުން، އެކަލޭގެފާނީ މޮޔައެކެވެ.","",""],["","","","وما هو إلا ذكر للعالمين","އާލަމްތަކަށް ހަނދާންކޮށްދިނުމެއްކަމުގައި މެނުވީ އެ ގުރްއާން ނުވެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم الحاقة","ކަށަވަރުވެގެންވާ ގިޔާމަތް ދުވަހެވެ.","",""],["","","","ما الحاقة","ކަށަވަރުވެގެންވާ ގިޔާމަތް ދުވަހަކީ، ކޮންދުވަހެއް ހެއްޔެވެ؟","",""],["","","","وما أدراك ما الحاقة","ކަށަވަރުވެގެންވާ ގިޔާމަތް ދުވަހަކީ، ކޮންދުވަހެއްކަން ކަލޭގެފާނަށް އަންގައިދިނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","كذبت ثمود وعاد بالقارعة","ޘަމޫދު ބާގައިމީހުންނާއި، ޢާދު ބާގައިމީހުން ގިޔާމަތް ދުވަސް ދޮގުކުރޫއެވެ.","",""],["","","","فأما ثمود فأهلكوا بالطاغية","ފަހެ، ޘަމޫދު ބާގައިމީހުން ދަންނާށެވެ! ފަހެ، ބިރުވެރި، ގަދަފަދަ އަޑުން އެއުރެން ހަލާކު ކުރެއްވިއެވެ.","",""],["","","","وأما عاد فأهلكوا بريح صرصر عاتية","އަދި ޢާދު ބާގައިމީހުން ދަންނާށެވެ! ފަހެ، ގަދަފަދަ ފިނިވަޔަކުން އެއުރެން ހަލާކު ކުރެއްވިއެވެ.","",""],["","","","سخرها عليهم سبع ليال وثمانية أيام حسوما فترى القوم فيها صرعى كأنهم أعجاز نخل خاوية","އެކަލާނގެ އެއުރެންގެ މައްޗަށް ހަތްރެޔާއި، އަށްދުވާ ވަންދެން ވިދިވިދިގެން އެ ވައި ފޮނުއްވިއެވެ. ފަހެ، އެ ގައުމުގެމީހުން ހޭނެތިގެން ވެއްޓިފައިވާތީ ތިބާ ދެކޭނޫއެވެ. އެއުރެންނެކޭ، ހޮއިހެދިފައިވާ ކަދުރު ރުކުގެ ބުޑުތަކެކޭ އެއްފަދައެވެ.","",""],["","","","فهل ترى لهم من باقية","ފަހެ، އެއުރެންގެ ތެރެއިން ސަލާމަތްވި އެކަކުވެސް ތިބާޔަށް ފެނޭހެއްޔެވެ؟","",""],["","","","وجاء فرعون ومن قبله والمؤتفكات بالخاطئة","އަދި ފިރްޢައުނާއި، އޭނާގެ ކުރީގެ މީހުންނާއި، ބަންޑުންޖެއްސެވި ރަށްތަކުގެ މީހުން ފާފަކުރޫއެވެ.","",""],["","","","فعصوا رسول ربهم فأخذهم أخذة رابية","ފަހެ، އެއުރެންގެ ވެރިރަސްކަލާނގެ ފޮނުއްވި ރަސޫލާއަށް އެއުރެން އުރެދުނޫއެވެ. ފަހެ، އެކަލާނގެ ގަދަފަދަވެގެންވާ އަޒާބުގެ ހިއްޕެވުމަކުން އެއުރެން ހިއްޕެވިއެވެ.","",""],["","","","إنا لما طغى الماء حملناكم في الجارية","ފެންގަނޑު ހައްދުފަހަނަޅައި އެރިހިނދު، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، ނައުކޮޅުގައި ތިޔަބައިމީހުން އުފުއްލެވީމެވެ.","",""],["","","","لنجعلها لكم تذكرة وتعيها أذن واعية","އެއީ ތިމަންރަސްކަލާނގެ އެކަންތައްތައް ތިޔަބައިމީހުންނަށް ހަނދާންކޮށްދެއްވުމެއް ކަމުގައި ލެއްވުމަށްޓަކައެވެ. އަދި ކަނުލައި އަހާ ކަންފަތްތަކެއް އެވާހަކަ ކަނުލައި އެހުމަށްޓަކައެވެ.","",""],["","","","فإذا نفخ في الصور نفخة واحدة","ފަހެ، ތާޅަފިލި އެއްފަހަރު ފުމެލައްވާ ހިނދެވެ.","",""],["","","","وحملت الأرض والجبال فدكتا دكة واحدة","އަދި ބިމާއި، ފަރުބަދަތައް (އެ ތަކެތި ހުރިތަނުން) އުފުލި އެއްފަހަރުން ޖެހި، ކުނޑި ކުނޑި ވެގެންދާ ހިނދެވެ.","",""],["","","","فيومئذ وقعت الواقعة","ފަހެ، އެދުވަހުން ގިޔާމަތްވާ ހުށްޓެވެ.","",""],["","","","وانشقت السماء فهي يومئذ واهية","އަދި އުޑު ފަޅަފަޅައިގެންދާނެތެވެ. ފަހެ، އެދުވަހުން އެ އުޑުވާހުށީ، ބަލިކަށިވެގެންނެވެ.","",""],["","","","والملك على أرجائها ويحمل عرش ربك فوقهم يومئذ ثمانية","އަދި މަލާއިކަތުން، އެ އުޑުގެ ކަންކޮޅުތަކުގައި ތިއްބަވާނެތެވެ. އެދުވަހުން ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ޢަރްޝުފުޅު، އެއުރެންގެ މަތީގައި އުފުއްލަވާނީ، އަށް މަލާއިކަތުންނެވެ.","",""],["","","","يومئذ تعرضون لا تخفى منكم خافية","އެދުވަހުން (ހިސާބު ބެއްލެވުމަށް) ތިޔަބައިމީހުން ހުށަހަޅުއްވާނެތެވެ. ތިޔަބައިމީހުންގެ އެއްވެސްކަމެއް ވަންހަނާއެއް ނުވާނެތެވެ.","",""],["","","","فأما من أوتي كتابه بيمينه فيقول هاؤم اقرءوا كتابيه","ފަހެ، އެމީހެއްގެ ފަތް، އެމީހެއްގެ ކަނާތަށް ލިބުނުމީހާ ދަންނާށެވެ! ފަހެ، އެމީހާ ބުނާނެތެވެ. މިއޮތީއެވެ. ތިޔަބައިމީހުން ތިމަންގެ ފަތް ކިޔައިބަލާށެވެ!","",""],["","","","إني ظننت أني ملاق حسابيه","ހަމަކަށަވަރުން، ތިމަންގެ ހިސާބުކުރިމަތިލާންޖެހޭނެކަން ތިމަންނާއަށް ޔަގީން ވިއެވެ.","",""],["","","","فهو في عيشة راضية","ފަހެ، އޭނާ ވާހުށީ، ރުހިގެންވާ ދިރިއުޅުމެއްގައެވެ.","",""],["","","","في جنة عالية","މަތިވެރިވެގެންވާ ސުވަރުގެޔެއްގައެވެ.","",""],["","","","قطوفها دانية","އެތާނގެ މޭވާތައް ކައިރިވެގެންވެއެވެ.","",""],["","","","كلوا واشربوا هنيئا بما أسلفتم في الأيام الخالية","(އަންގަވާނެތެވެ.) އަރާމުލިބެނިވިގޮތުގައި، ތިޔަބައިމީހުން ކައިބޮއި އުޅޭށެވެ! ދުނިޔޭގައި ތިޔަބައިމީހުން ހޭދަކުރި ދުވަސްތަކުގައި ތިޔަބައިމީހުންކުރި ހެޔޮ ޢަމަލުތަކުގެ ޖަޒާއެއްގެ ގޮތުންނެވެ.","",""],["","","","وأما من أوتي كتابه بشماله فيقول يا ليتني لم أوت كتابيه","އަދި އެމީހެއްގެ ފަތް، އެމީހެއްގެ ވާތަށް ލިބުނުމީހާ ދަންނާށެވެ! ފަހެ، އެމީހާ ބުނާނެތެވެ. އޭ ސަހަރޯއެވެ! ތިމަންގެ ފަތް ތިމަންގެ އަތަށް ނުދެއްވެވިނަމަ ކިހާ ރަނގަޅުވީސް ހެއްޔެވެ؟","",""],["","","","ولم أدر ما حسابيه","އަދި ތިމަންގެ ހިސާބު ތިމަންނާއަށް ނޭނގުނުނަމަ ކޮންފަދަހެއްޔެވެ!","",""],["","","","يا ليتها كانت القاضية","އޭ ސަހަރޯއެވެ! އެ މަރު އެއީ، ތިމަންނާގެ ނިމުންކަމުގައިވީނަމަ، ކޮންފަދަހެއްޔެވެ!","",""],["","","","ما أغنى عني ماليه","ތިމަންގެ މުދާ، ތިމަންނާއަށް އެއްވެސްކަމެއް ފުއްދައެއް ނުދިނެވެ.","",""],["","","","هلك عني سلطانيه","ތިމަންގެ އާރާއި ބާރު، ތިމަންގެ ކިބައިން ފިލައިހިނގައްޖެއެވެ.","",""],["","","","خذوه فغلوه","(ޒަބާނިއްޔަ މަލާއިކަތުންނަށް ﷲ އަންގަވާނެތެވެ.) އޭނާ ހިފައި ކަސްތޮޅު އަޅާށެވެ!","",""],["","","","ثم الجحيم صلوه","ދެން އޭނާ ނަރަކަޔަށް ވައްދާށެވެ!","",""],["","","","ثم في سلسلة ذرعها سبعون ذراعا فاسلكوه","ދެން ހަތްދިހަ މުށުގެ ދިގުމިންހުރި ހިލިހިލާއެއްގައި އޭނާ ހިލިހިލާ ޖަހާށެވެ!","",""],["","","","إنه كان لا يؤمن بالله العظيم","ހަމަކަށަވަރުން، އޭނާ މާތް ﷲއަށް އީމާން ވާކަމުގައެއް ނުވެއެވެ.","",""],["","","","ولا يحض على طعام المسكين","އަދި މިސްކީނުންނަށް ކާންދިނުމަކަށް އޭނާ ބާރުއަޅާކަމުގައެއް ނުވެއެވެ.","",""],["","","","فليس له اليوم هاهنا حميم","ފަހެ، މިއަދު މިތާކު އޭނާއަކަށް ރަހުމަތް ތެރިޔަކު ނުވެއެވެ.","",""],["","","","ولا طعام إلا من غسلين","އަދި ޣިސްލީނު މެނުވީ (އެބަހީ: ނަރަކައިގެ އަހުލުވެރިންގެ ގައިން އޮހޮރޭ ފާ ދިޔަ މެނުވީ) އޭނާޔަކަށް ކާއެއްޗެއް ނުވެއެވެ.","",""],["","","","لا يأكله إلا الخاطئون","ކުށްވެރިން މެނުވީ އެ އެއް ނުކާނެތެވެ.","",""],["","","","فلا أقسم بما تبصرون","ފަހެ، ތިޔަބައިމީހުންނަށް ފެންނަ ތަކެއްޗާއި، ތިޔަބައިމީހުންނަށް ނުފެންނަ ތަކެތި ގަންދެއްވައި ވަހީކުރައްވަމެވެ.","",""],["","","","وما لا تبصرون","ފަހެ، ތިޔަބައިމީހުންނަށް ފެންނަ ތަކެއްޗާއި، ތިޔަބައިމީހުންނަށް ނުފެންނަ ތަކެތި ގަންދެއްވައި ވަހީކުރައްވަމެވެ.","",""],["","","","إنه لقول رسول كريم","ހަމަކަށަވަރުން، އެއީ މާތްވެގެންވާ ރަސޫލަކު (އެބަހީ: ޖިބްރީލުގެފާނު ﷲގެ ހަޒުރަތުން) ގެންނެވި ބަސްފުޅެއްކަން ކަށަވަރެވެ.","",""],["","","","وما هو بقول شاعر قليلا ما تؤمنون","އެއީ ޅެންވެރިޔެއްގެ ބަހެއްނޫނެވެ. ތިޔަބައިމީހުން އީމާން ވަނީ ވަރަށްވެސް ކުޑަކޮށެވެ.","",""],["","","","ولا بقول كاهن قليلا ما تذكرون","އަދި އެއީ ކާހިނެއްގެ ބަހެއްވެސްނޫނެވެ. ތިޔަބައިމީހުން ހަނދުމަކުރަނީ ވަރަށްވެސް މަދުންނެވެ.","",""],["","","","تنزيل من رب العالمين","(އެއީ) އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ބާވައިލެއްވި ފޮތެކެވެ.","",""],["","","","ولو تقول علينا بعض الأقاويل","އަދި އެކަލޭގެފާނު ތިމަންރަސްކަލާނގެއަށް ނިސްބަތްކޮށް ހަދައިގެން ބައެއް ވާހަކަ ދައްކަވައިފިނަމަ، ތިމަންރަސްކަލާނގެ ބާރުވެރިކަމުން އެކަލޭގެފާނު (ކިބައިން އިންތިގާމް) ހިއްޕެވީމުހެވެ.","",""],["","","","لأخذنا منه باليمين","އަދި އެކަލޭގެފާނު ތިމަންރަސްކަލާނގެއަށް ނިސްބަތްކޮށް ހަދައިގެން ބައެއް ވާހަކަ ދައްކަވައިފިނަމަ، ތިމަންރަސްކަލާނގެ ކަނާތްޕުޅުން އެކަލޭގެފާނު (ކިބައިން އިންތިގާމް) ހިއްޕެވީމުހެވެ.","",""],["","","","ثم لقطعنا منه الوتين","ދެން ތިމަންރަސްކަލާނގެ، އެކަލޭގެފާނުގެ ހިތްޕުޅުގެ ނާރު ކަނޑުއްވައިފީމުހެވެ.","",""],["","","","فما منكم من أحد عنه حاجزين","ފަހެ، ތިޔަބައިމީހުންކުރެ އެކަކަށްވެސް އެކަލޭގެފާނު ތިމަންރަސްކަލާނގެ އަޒާބުން ދުރެއްނުކުރެވޭނެތެވެ.","",""],["","","","وإنه لتذكرة للمتقين","ހަމަކަށަވަރުން، އެ ގުރްއާނަކީ، ތަގުވާވެރިންނަށް އޮތް ހަނދާންކޮށްދިނުމެއްކަން ކަށަވަރެވެ.","",""],["","","","وإنا لنعلم أن منكم مكذبين","އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ ތެރެއިން ދޮގުކުރާ ބަޔަކުވާކަން ތިމަންރަސްކަލާނގެ ދެނެވޮޑިގެންވަމެވެ.","",""],["","","","وإنه لحسرة على الكافرين","އަދި ހަމަކަށަވަރުން، އެ ގުރްއާނަކީ، ކާފިރުންގެ މައްޗަށްހުރި ހިތާމައެއްކަން ކަށަވަރެވެ.","",""],["","","","وإنه لحق اليقين","އަދި ހަމަކަށަވަރުން، އެ ގުރްއާނަކީ، ޔަގީން ވެގެންވާ ހައްގު ތެދުކަން ކަށަވަރެވެ.","",""],["","","","فسبح باسم ربك العظيم","ފަހެ، ކަލޭގެފާނުގެ ވެރި މާތްވަންތަ ރަސްކަލާނގެ އިސްމުފުޅުން ކަލޭގެފާނު ތަސްބީހަ ވިދާޅުވާށެވެ!","",""],["","","","بسم الله الرحمن الرحيم سأل سائل بعذاب واقع","އެދޭމީހަކު (ފުރައްސާރައިގެގޮތުން) އަޒާބަކަށްއެދި ގޮވިއެވެ. (އެއީ) ކާފިރުންނަށްޖެހޭނޭ އަޒާބެކެވެ. އުޑުތަކުގެ ވެރި ﷲގެ ހަޒުރަތުން އަންނަ އަޒާބު ދުރުކޮށްދޭނޭ ހަމައެކަކުވެސް ނުވެތެވެ.","",""],["","","","للكافرين ليس له دافع","އެދޭމީހަކު (ފުރައްސާރައިގެގޮތުން) އަޒާބަކަށްއެދި ގޮވިއެވެ. (އެއީ) ކާފިރުންނަށްޖެހޭނޭ އަޒާބެކެވެ. އުޑުތަކުގެ ވެރި ﷲގެ ހަޒުރަތުން އަންނަ އަޒާބު ދުރުކޮށްދޭނޭ ހަމައެކަކުވެސް ނުވެތެވެ.","",""],["","","","من الله ذي المعارج","އެދޭމީހަކު (ފުރައްސާރައިގެގޮތުން) އަޒާބަކަށްއެދި ގޮވިއެވެ. (އެއީ) ކާފިރުންނަށްޖެހޭނޭ އަޒާބެކެވެ. އުޑުތަކުގެ ވެރި ﷲގެ ހަޒުރަތުން އަންނަ އަޒާބު ދުރުކޮށްދޭނޭ ހަމައެކަކުވެސް ނުވެތެވެ.","",""],["","","","تعرج الملائكة والروح إليه في يوم كان مقداره خمسين ألف سنة","ފަންސާސްހާސް އަހަރުގެ މިންވަރުގެ ދުވަހެއްގައި، މަލާއިކަތްނާއި، ޖިބްރީލުގެފާނު، އެކަލާނގެ ހަޒުރަތަށް އަރާވަޑައިގަންނަވާނެތެވެ.","",""],["","","","فاصبر صبرا جميلا","ފަހެ، ކަލޭގެފާނު ރިވެތިވެގެންވާ ކެތްކުރެއްވުމަކުން ކެތްކުރައްވާށެވެ!","",""],["","","","إنهم يرونه بعيدا","ހަމަކަށަވަރުން، އެއުރެން އެދުވަސް ދެކެނީ، ދުރުވެގެންވާ ކަމަށެވެ.","",""],["","","","ونراه قريبا","އަދި ތިމަންރަސްކަލާނގެ ދެކެވޮޑިގަންނަވަނީ، އެދުވަސް ގާތްކަމުގައެވެ.","",""],["","","","يوم تكون السماء كالمهل","ތެޔޮކުނޑިތަކެއް ފަދައިން އުޑު، ވާނޭދުވަހުއެވެ.","",""],["","","","وتكون الجبال كالعهن","އަދި، ފިނދިފައިވާ ކެހެރިތަކެއް ފަދައިން ފަރުބަދަތައް ވާނޭދުވަހުއެވެ.","",""],["","","","ولا يسأل حميم حميما","އަދި، އެދުވަހުން ގާތް ރަހުމަތް ތެރިޔަކު، ރަހުމަތް ތެރިޔަކާމެދު ސުވާލެއް ނުކުރާނެތެވެ.","",""],["","","","يبصرونهم يود المجرم لو يفتدي من عذاب يومئذ ببنيه","އެއުރެން އެކަކު އަނެކަކަށް ފެންނާނެގޮތް މެދުވެރިކުރައްވާނެތެވެ. އެދުވަހުގެ އަޒާބުން ސަލާމަތްވުމަށް ކުށްވެރިޔާ އޭނާގެ ދަރިން، ފިދުޔެއްގެ ގޮތުގައި ދެވޭނެނަމައޭ ހިތައި އެކަމަށް އެދޭނެތެވެ.","",""],["","","","وصاحبته وأخيه","އަދި، އޭނާގެ އަނބިމީހާއާއި، އޭނާގެ އަޚު ވެސްމެއެވެ.","",""],["","","","وفصيلته التي تؤويه","އަދި، އޭނާޔަށް ހިޔާވަހިކަންދޭ، އޭނާގެ ގާތްތިމާގެ މީހުންވެސްމެއެވެ.","",""],["","","","ومن في الأرض جميعا ثم ينجيه","އަދި، ބިމުގައިވާހާ އެންމެންވެސްމެއެވެ. ދެން، އެ ފިދުޔަ އޭނާ ސަލާމަތް ކުރޭތޯއެވެ.","",""],["","","","كلا إنها لظى","ހަމަ ހިލާ އެހެންނަކުން ނުވާނެއެވެ. ހަމަކަށަވަރުން، އެ ނަރަކައީ އަނދައަނދާހުރި އަލިފާނެވެ.","",""],["","","","نزاعة للشوى","(އޭގެ ހޫނުން) ބޮލުގެ ހަން ނޮޅާ ޙާލު ގައެވެ.","",""],["","","","تدعو من أدبر وتولى","ފުރަގަސްދީ އެނބުރިދާ މީހާޔަށް އެ ނަރަކަ ގޮވާނެތެވެ.","",""],["","","","وجمع فأوعى","އަދި މުދާ އެއްކޮށް، ޚަޒާނާކުރާ މީހާޔަށްވެސްމެއެވެ.","",""],["","","","إن الإنسان خلق هلوعا","ހަމަކަށަވަރުން، އިންސާނާ ހައްދަވާފައިވަނީ، ކެތްތެރިކަންކުޑަ މީހެއްގެ ގޮތުގައެވެ.","",""],["","","","إذا مسه الشر جزوعا","އެ އިންސާނާގައި ނުބައިކަމެއް ބީހިއްޖެނަމަ، ކެތްތެރިކަންކުޑަ މީހެއްގެ ގޮތުގައެވެ.","",""],["","","","وإذا مسه الخير منوعا","އަދި އޭނާގައި ހެޔޮކަމެއް ބީހިއްޖެނަމަ (އެބަހީ: ތަނަވަސްކަމެއް ލިބިއްޖެނަމަ، އެއިން ހޭދަކުރުމުން) މަނާވެގަންނަ މީހެއްގެ ގޮތުގައެވެ.","",""],["","","","إلا المصلين","ނަމާދުކުރާ މީހުން މެނުވީއެވެ.","",""],["","","","الذين هم على صلاتهم دائمون","އެއުރެންނީ، އެއުރެންގެ ނަމާދުކުރުންމަތީ ދެމިތިބޭމީހުންނެވެ.","",""],["","","","والذين في أموالهم حق معلوم","އަދި، އެއުރެންނީ، ސުވާލު ކޮށް، އެދޭމީހުންނަށާއި، ނިކަމެތި މަޙްރޫމުންނަށް، އެއުރެންގެ މުދަލުގައި ކަނޑައެޅިގެންވާ ހައްގެއްވާ މީހުންނެވެ.","",""],["","","","للسائل والمحروم","އަދި، އެއުރެންނީ، ސުވާލު ކޮށް، އެދޭމީހުންނަށާއި، ނިކަމެތި މަޙްރޫމުންނަށް، އެއުރެންގެ މުދަލުގައި ކަނޑައެޅިގެންވާ ހައްގެއްވާ މީހުންނެވެ.","",""],["","","","والذين يصدقون بيوم الدين","އަދި، އެއުރެންނީ، ގިޔާމަތް ދުވަހަށް އީމާންވެ، ތެދުކުރާ މީހުންނެވެ.","",""],["","","","والذين هم من عذاب ربهم مشفقون","އަދި، އެއުރެންނީ، އެއުރެންގެ ވެރިރަސްކަލާނގެ އަޒާބަށް ބިރުވެތިވާ މީހުންނެވެ.","",""],["","","","إن عذاب ربهم غير مأمون","ހަމަކަށަވަރުން، އެއުރެންގެ ވެރިރަސްކަލާނގެ އަޒާބަކީ (އެކަލާނގެ އަމާން ކަންދެއްވިއްޔާމެނުވީ އެއިން) އަމާން ކަން ލިބިގެންނުވާ އަޒާބެކެވެ.","",""],["","","","والذين هم لفروجهم حافظون","އަދި، އެއުރެންނީ، އެއުރެންގެ ފަރުޖުތަކަށް ރައްކާތެރިވާ މީހުންނެވެ.","",""],["","","","إلا على أزواجهم أو ما ملكت أيمانهم فإنهم غير ملومين","އެއުރެންގެ އަނބިންގެ މައްޗަށާއި، އެއުރެންނަށް މިލްކުވެގެންވާ އަޅުންގެ މައްޗަށް މެނުވީއެވެ. ފަހެ، ހަމަކަށަވަރުން، އެއުރެންނީ (އެކަމުގައި) މަލާމާތް ލިބިގެންނުވާ މީހުންނެވެ.","",""],["","","","فمن ابتغى وراء ذلك فأولئك هم العادون","ފަހެ، އެއިން ބޭރުގައިވާ ކަމަކަށް އެދިއްޖެމީހާ (ދަންނާށެވެ!) ފަހެ، އެއުރެންނީ (ހުއްދަވެގެންވާ ސަރަޙައްދު) ފަހަނަޅައިދާ މީހުންނެވެ.","",""],["","","","والذين هم لأماناتهم وعهدهم راعون","އަދި، އެއުރެންނީ، އެއުރެންގެ އަމާނަތް ތަކަށާއި، އެއުރެންގެ އަހުދުތަކަށް ރައްކާތެރިވާ މީހުންނެވެ.","",""],["","","","والذين هم بشهاداتهم قائمون","އެއުރެންނީ، އެއުރެންގެ ހެކިބަސް ފުރިހަމަޔަށް އަދާކުރާ މީހުންނެވެ.","",""],["","","","والذين هم على صلاتهم يحافظون","އަދި، އެއުރެންނީ، އެއުރެންގެ ނަމާދުގެ މައްޗަށް ރައްކާތެރިވާ މީހުންނެވެ.","",""],["","","","أولئك في جنات مكرمون","އެއުރެންވަނީ، ސުވަރުގެތަކެއްގައި މާތްކުރައްވާފައެވެ.","",""],["","","","فمال الذين كفروا قبلك مهطعين","ފަހެ، ކާފިރު ވިމީހުން (ކަލޭގެފާނުގެ) ކަނާތްފަރާތުގައްޔާއި، ވާތްފަރާތުގައި ބައިބަޔަށް (އިށީނދެ) ތިބެން ކަލޭގެފާނުގެ އަރިހަށް ދިޔުމަށް އަވަސްވެގަންނަނީ ކީއްވެހެއްޔެވެ؟","",""],["","","","عن اليمين وعن الشمال عزين","ފަހެ، ކާފިރު ވިމީހުން (ކަލޭގެފާނުގެ) ކަނާތްފަރާތުގައްޔާއި، ވާތްފަރާތުގައި ބައިބަޔަށް (އިށީނދެ) ތިބެން ކަލޭގެފާނުގެ އަރިހަށް ދިޔުމަށް އަވަސްވެގަންނަނީ ކީއްވެހެއްޔެވެ؟","",""],["","","","أيطمع كل امرئ منهم أن يدخل جنة نعيم","ނިއުމަތްގެ ސުވަރުގެޔަށް ވެއްދެވުމަށް އެއިންކޮންމެ މީހަކު ދަހިވެތިވަނީ ހެއްޔެވެ؟","",""],["","","","كلا إنا خلقناهم مما يعلمون","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެއުރެން ހެއްދެވީ، އެއުރެން ދަންނަ އެއްޗަކުންނެވެ.","",""],["","","","فلا أقسم برب المشارق والمغارب إنا لقادرون","ފަހެ، މަޝްރިގު ތަކާއި، މަޣްރިބުތަކުގެ ވެރިރަސްކަލާނގެ ގަންދެއްވައި ވަހީކުރައްވަމެވެ. އެއުރެންގެ ބަދަލުގައި، އެއުރެންނަށްވުރެން ހެޔޮބަޔަކު ގެންނެވުމަށް ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކުޅަދުންވަންތަކަން ކަށަވަރެވެ. އަދި ތިމަންރަސްކަލާނގެ ނުކުޅެދިވޮޑިގެންވާ ކަލަކުކަމުގައި ނުވަމެވެ.","",""],["","","","على أن نبدل خيرا منهم وما نحن بمسبوقين","ފަހެ، މަޝްރިގު ތަކާއި، މަޣްރިބުތަކުގެ ވެރިރަސްކަލާނގެ ގަންދެއްވައި ވަހީކުރައްވަމެވެ. އެއުރެންގެ ބަދަލުގައި، އެއުރެންނަށްވުރެން ހެޔޮބަޔަކު ގެންނެވުމަށް ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކުޅަދުންވަންތަކަން ކަށަވަރެވެ. އަދި ތިމަންރަސްކަލާނގެ ނުކުޅެދިވޮޑިގެންވާ ކަލަކުކަމުގައި ނުވަމެވެ.","",""],["","","","فذرهم يخوضوا ويلعبوا حتى يلاقوا يومهم الذي يوعدون","ފަހެ، އެއުރެންނަށް ވައުދުކުރައްވާ ދުވަހާ އެއުރެން ބައްދަލުވެއްޖައުމަށް ދާނދެން، ބާތިލު ވާހަކަތައް ދައްކައި، ކުޅިވަރުކުޅެން ކަލޭގެފާނު އެއުރެން ދޫކޮށްލައްވާށެވެ!","",""],["","","","يوم يخرجون من الأجداث سراعا كأنهم إلى نصب يوفضون","(އެއީ) ކަށްވަޅުތަކުން ނުކުމެގެން އެއުރެން އަވަސްއަވަހަށް ހިނގައިދާދުވަހެވެ. އެއުރެން އަޅުކަންކުރާ ބުދުތަކުގެ ކައިރިޔަށް އަވަސްއަވަހަށްދާ ފަދައިންނެވެ.","",""],["","","","خاشعة أبصارهم ترهقهم ذلة ذلك اليوم الذي كانوا يوعدون","(އެއުރެން ތިބޭހުށީ) އެއުރެންގެ ލޯތައް ތިރިވެގެންވާ ޙާލު، އެއުރެންގެ މައްޗަށް ނިކަމެތިކަން ވެރިވެފައެވެ. އެއީ، އެއުރެންނަށް ވައުދުކުރައްވާކަމުގައިވީ ދުވަހެވެ.","",""],["","","","بسم الله الرحمن الرحيم إنا أرسلنا نوحا إلى قومه أن أنذر قومك من قبل أن يأتيهم عذاب أليم","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، ނޫޙުގެފާނު އެކަލޭގެފާނުގެ ގައުމުގެމީހުންގެ ގާތަށް ރަސޫލުކަމާއިގެން ފޮނުއްވީމެވެ. ކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް އިންޒާރުކުރައްވާށޭ އަންގަވަމުންނެވެ. (އެއީ) އެއުރެންނަށް ވޭންދެނިވި އަޒާބު އައުމުގެ ކުރިންނެވެ.","",""],["","","","قال يا قوم إني لكم نذير مبين","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އޭ، އަހުރެންގެ ގައުމުގެމީހުންނޭވެ! ހަމަކަށަވަރުން، އަހުރެންނީ، ތިޔަބައިމީހުންނަށް ބަޔާންވެގެންހުރި އިންޒާރުކުރާ މީޙަކީމެވެ.","",""],["","","","أن اعبدوا الله واتقوه وأطيعون","(ވިދާޅުވަމުންނެވެ.) ތިޔަބައިމީހުން ﷲއަށް އަޅުކަންކުރާށެވެ! އަދި ތިޔަބައިމީހުން، އެކަލާނގެއަށް ތަގުވާވެރިވާށެވެ! އަދި ތިޔަބައިމީހުން އަހުރެންނަށް ކިޔަމަންވާށެވެ!","",""],["","","","يغفر لكم من ذنوبكم ويؤخركم إلى أجل مسمى إن أجل الله إذا جاء لا يؤخر لو كنتم تعلمون","(އޭރުން) އެކަލާނގެ، ތިޔަބައިމީހުންގެ ފާފަތައް ތިޔަބައިމީހުންނަށްޓަކައި ފުއްސަވައިދެއްވާނެތެވެ. އަދި ކަނޑައަޅުއްވާފައިވާ މުއްދަތަކަށް ތިޔަބައިމީހުން ފަސްކުރައްވާނެތެވެ. ހަމަކަށަވަރުން، ﷲ ކަނޑައަޅުއްވާފައިވާ އަޖަލު އަތުވެއްޖެނަމަ، ލަހެއް ނުކުރައްވާނެތެވެ. ތިޔަބައިމީހުންނަށް (އެކަން) އެނގޭކަމުގައި ވާނަމައެވެ.","",""],["","","","قال رب إني دعوت قومي ليلا ونهارا","އެކަލޭގެފާނު ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނުގެ ގައުމުގެމީހުންނަށް (އީމާން ވުމަށް) ރެއާއި، ދުވާލު ތިމަންކަލޭގެފާނު ގޮވައިލެއްވީމެވެ.","",""],["","","","فلم يزدهم دعائي إلا فرارا","ފަހެ، ތިމަންކަލޭގެފާނުގެ ގޮވައިލެއްވުން، ފިލާންދިޔުން ނޫންކަމެއް އެއުރެންނަކަށް އިތުރެއް ނުކުރިއެވެ. (އެބަހީ: އެކަލޭގެފާނު ތެދުމަގަށް ގޮވައިލެއްވިވަރަކަށް، އެއުރެންދަނީ، އެކަލޭގެފާނުގެ ދައުވާއާ ދުރަށެވެ.)","",""],["","","","وإني كلما دعوتهم لتغفر لهم جعلوا أصابعهم في آذانهم واستغشوا ثيابهم وأصروا واستكبروا استكبارا","އަދި ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެ އެއުރެންގެ ފާފަފުއްސެވުމަށްޓަކައި، ތިމަންކަލޭގެފާނު އެއުރެންނަށް (އީމާން ވުމަށް) ގޮވައިލައްވާ ކޮންމެ ފަހަރަކު، އެއުރެންގެ އިނގިލިތައް، އެއުރެންގެ ކަންފަތްތަކުގައި އަޅަތެވެ. އަދި އެއުރެންގެ ފޭރާމުން، އެއުރެން ނިވާވެގަނެތެވެ. އަދި އެއުރެން (ކުފުރުވެރިކަންމަތީ) ދެމިތިބެތެވެ. އަދި ނުހަނު ބޮޑާވެގަނެތެވެ.","",""],["","","","ثم إني دعوتهم جهارا","ދެން ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނު އެއުރެންނަށް ހަރުއަޑުން ގޮވައިލެއްވީމެވެ.","",""],["","","","ثم إني أعلنت لهم وأسررت لهم إسرارا","ދެން ހަމަކަށަވަރުން، ތިމަންކަލޭގެފާނު އެއުރެންނަށް ފާޅުގައި ގޮވައިލެއްވީމެވެ. އަދި ތިމަންކަލޭގެފާނު ވަންހަނާކޮށް ސިއްރުކުރައްވައި، އެއުރެންނަށް ގޮވައިލެއްވީމެވެ.","",""],["","","","فقلت استغفروا ربكم إنه كان غفارا","ފަހެ، ތިމަންކަލޭގެފާނު ވިދާޅުވީމެވެ. ތިޔަބައިމީހުންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ފާފަފުއްސެވުމަށްއެދި، ތިޔަބައިމީހުން ދަންނަވާށެވެ! ހަމަކަށަވަރުން، އެކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ ރަސްކަލާނގެކަމުގައިވެއެވެ.","",""],["","","","يرسل السماء عليكم مدرارا","(އޭރުން) އެކަލާނގެ ތިޔަބައިމީހުންގެ މައްޗަށް ބޯކޮށް (ވެހޭގޮތުގައި) ވާރޭ ފޮނުއްވާނެތެވެ.","",""],["","","","ويمددكم بأموال وبنين ويجعل لكم جنات ويجعل لكم أنهارا","އަދި މުދާތަކާއި، ދަރިންގެގޮތުން، އެކަލާނގެ ތިޔަބައިމީހުންނަށް މަދަދު ދެއްވާނެތެވެ. އަދި އެކަލާނގެ ތިޔަބައިމީހުންނަށްޓަކައި ބަގީޗާތައް ލައްވާނެތެވެ. އަދި އެކަލާނގެ ތިޔަބައިމީހުންނަށްޓަކައި ކޯރުތައްވެސް ލައްވާނެތެވެ.","",""],["","","","ما لكم لا ترجون لله وقارا","ތިޔަބައިމީހުން ﷲގެ ޢަޡަމަތް ތެރިކަމަށް އިޢުތިގާދު ނުކުރަނީ ކީއްވެގެންހެއްޔެވެ؟","",""],["","","","وقد خلقكم أطوارا","ހަމަކަށަވަރުން، އެކަލާނގެ ތިޔަބައިމީހުން ހެއްދެވީ، ތަފާތު މަރުޙަލާ ތަކަކުންނެވެ.","",""],["","","","ألم تروا كيف خلق الله سبع سماوات طباقا","މަތިމައްޗަށް ﷲ، ހަތް އުޑުހެއްދެވީ ކިހިނަކުންކަން ތިޔަބައިމީހުން ބަލައި ނުވިސްނަނީ ހެއްޔެވެ؟","",""],["","","","وجعل القمر فيهن نورا وجعل الشمس سراجا","އަދި އެކަލާނގެ އެ އުޑުތަކުގައި ހަނދު ނޫރެއްކަމުގައި ލެއްވިއެވެ. އަދި އެކަލާނގެ އިރު، ވޮށެއްގެ ގޮތުގައި ލެއްވިއެވެ.","",""],["","","","والله أنبتكم من الأرض نباتا","އަދި ﷲ، ތިޔަބައިމީހުން ބިމުން އުފައްދަވައި ހެއްދެވިއެވެ.","",""],["","","","ثم يعيدكم فيها ويخرجكم إخراجا","ދެން އެކަލާނގެ ތިޔަބައިމީހުން އެ ބިމަށް އިއާދަކުރައްވާނެތެވެ. އަދި އެކަލާނގެ ތިޔަބައިމީހުން (އެ ބިމުން) ނެރުއްވާނެތެވެ.","",""],["","","","والله جعل لكم الأرض بساطا","އަދި ﷲ، ތިޔަބައިމީހުންނަށްޓަކައި ފެތުރިގެންވާ ދޫލައެއްގެ ގޮތުގައި ބިންގަނޑުލެއްވިއެވެ.","",""],["","","","لتسلكوا منها سبلا فجاجا","(އެއީ) އެބިމުން ތިޔަބައިމީހުން ތަނަވަސް މަގުތައް ހޯދައިގަތުމަށްޓަކައެވެ.","",""],["","","","قال نوح رب إنهم عصوني واتبعوا من لم يزده ماله وولده إلا خسارا","ނޫޙުގެފާނު ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ހަމަކަށަވަރުން، އެއުރެން މިއަޅާޔަށް އުރެދިއްޖައޫއެވެ. އަދި އެއުރެންގެ މުދަލުންނާއި، ދަރިންގެ ފަރާތުން އެއުރެންނަށް ގެއްލުމެއްނޫން އެހެންކަމެއް ނުލިބޭ މީހުނާ އެއުރެން ތަބާ ވެއްޖައޫއެވެ.","",""],["","","","ومكروا مكرا كبارا","އަދި އެއުރެން ބޮޑުވެގެންވާ މަކަރުވެރި ރޭވުމެއް ރޭވޫއެވެ.","",""],["","","","وقالوا لا تذرن آلهتكم ولا تذرن ودا ولا سواعا ولا يغوث ويعوق ونسرا","އަދި އެއުރެން ބުނޫއެވެ. ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ އިލާހު ންތައް ތިޔަބައިމީހުން ދޫނުކުރާހުށިކަމެވެ! އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ވައްދާއި، ސުވާޢާއި، ޔަޣޫޘާއި، ޔަޢޫގާއި، ނަސްރާއި (މިހުރިހާ ބުދުތައް) ދޫކޮށްނުލާހުށިކަމެވެ!","",""],["","","","وقد أضلوا كثيرا ولا تزد الظالمين إلا ضلالا","އަދި ހަމަކަށަވަރުން، އެއުރެން ގިނަބަޔަކު މަގުފުރެއްދޫއެވެ. އަނިޔާވެރިންނަށް މަގުފުރެދުން ނޫން އެހެންކަމެއް އިތުރު ނުކުރައްވާނދޭވެ!","",""],["","","","مما خطيئاتهم أغرقوا فأدخلوا نارا فلم يجدوا لهم من دون الله أنصارا","އެއުރެންގެ ފާފަތަކުގެ ސަބަބުން އެއުރެން ޣަރަގުކުރެއްވިއެވެ. ދެން އެއުރެން އަލިފާނަށް ވެއްދެވިއެވެ. ފަހެ، ﷲ ފިޔަވައި ނަސްރު ދޭނޭ ބަޔަކު އެއުރެންނަކަށް ނުފެނުނޫއެވެ.","",""],["","","","وقال نوح رب لا تذر على الأرض من الكافرين ديارا","އަދި ނޫޙުގެފާނު ވިދާޅުވިއެވެ. އަޅުގެ ވެރިރަސްކަލާކޮ! ކާފިރުންގެ ތެރެއިން ހަމައެކަކުވެސް އިބަރަސްކަލާނގެ މި ބިންމަތީގައި ނުބަހައްޓަވާނދޭވެ!","",""],["","","","إنك إن تذرهم يضلوا عبادك ولا يلدوا إلا فاجرا كفارا","ހަމަކަށަވަރުން، އިބަރަސްކަލާނގެ އެއުރެން ދޫކުރައްވައިފިނަމަ، އެއުރެން އިބަރަސްކަލާނގެ އަޅުތަކުން މަގުފުރައްދާނެތެވެ. އަދި އެއުރެން ފާޖިރު، ކުފުރުވެރިކަން ބޮޑު ދަރިޔަކުމެނުވީ ނުވެސް ވިހާނެތެވެ.","",""],["","","","رب اغفر لي ولوالدي ولمن دخل بيتي مؤمنا وللمؤمنين والمؤمنات ولا تزد الظالمين إلا تبارا","އަޅުގެ ވެރިރަސްކަލާކޮ! މިއަޅާޔާއި، މިއަޅާގެ މައިންބަފައިންނާއި، އީމާން ވެގެންހުރެ މިއަޅާގެ ގެޔަށް ވަދެއްޖެ މީހަކާއި، މުއުމިނު ފިރިހެނުންނާއި، މުއުމިނު އަންހެނުންނަށް ފާފަފުއްސަވާނދޭވެ! އަދި އަނިޔާވެރިންނަށް ހަލާކުނޫން އެހެންކަމެއް އިތުރު ނުކުރައްވާނދޭވެ!","",""],["","","","بسم الله الرحمن الرحيم قل أوحي إلي أنه استمع نفر من الجن فقالوا إنا سمعنا قرآنا عجبا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ޖިންނީންގެ ތެރެއިން ބަޔަކު (ގުރްއާންގެ) އަޑު އަހައިފިކަމަށް، ތިމަންކަލޭގެފާނަށް ވަހީ އިއްވަވައިފިއެވެ. ފަހެ (އެއުރެންގެ ގައުމުގެމީހުންނަށް) އެއުރެން ބުނޫއެވެ. ހަމަކަށަވަރުން، ތިމަންމެން އަޖާއިބު ވާފަދަ ގުރްއާނެއްގެ އަޑު އަހައިފީމުއެވެ.","",""],["","","","يهدي إلى الرشد فآمنا به ولن نشرك بربنا أحدا","އެ ގުރްއާން މަގުދައްކަނީ، ހައްގު ތެދުމަގަށެވެ. ފަހެ، ތިމަންމެން އެ ގުރްއާނަށް އީމާން ވެއްޖައީމުއެވެ. އަދި ތިމަންމެންގެ ވެރިރަސްކަލާނގެއާ އެއްވެސް އެއްޗެއް ތިމަންމެން ޝަރީކެއް ނުކުރާނަމެވެ.","",""],["","","","وأنه تعالى جد ربنا ما اتخذ صاحبة ولا ولدا","އަދި އަޅަމެންގެ ވެރިރަސްކަލާނގެ ޢަޡަމަތް ތެރިކަން މަތިވެރިވެގެންވެއެވެ. އަދި އެކަލާނގެ އަނބިކަނބަލަކުވެސް، އަދި ދަރިކަލަކުވެސް ނުހިއްޕަވައެވެ.","",""],["","","","وأنه كان يقول سفيهنا على الله شططا","އަދި ތިމަންމެންގެ ތެރެއިން ޖާހިލު ކަންބޮޑު މީހާ، ﷲއާމެދު ހައްގުން އެއްކިބާވެ، ހައްދުފަހަނަޅައިފައިވާ ބަސްބުނާކަމުގައިވިއެވެ.","",""],["","","","وأنا ظننا أن لن تقول الإنس والجن على الله كذبا","އަދި ﷲއާމެދު އިންސިޔަކުވެސް، އަދި ޖިންނިޔަކުވެސް އެއްވެސް ދޮގެއް ނުބުނާނެކަމަށް ތިމަންމެން ހީކުރީމުއެވެ.","",""],["","","","وأنه كان رجال من الإنس يعوذون برجال من الجن فزادوهم رهقا","އަދި އިންސީންގެ ތެރެއިން ފިރިހެންބަޔަކު، ޖިންނީންގެ ތެރެއިން ފިރިހެންބަޔެއްގެ ކިބައިން ރައްކާތެރިކަމަށް އެދޭކަމުގައިވޫއެވެ. ފަހެ (އެކަމުގެ ސަބަބުން) އެއުރެންނަށް (އެބަހީ: ޖިންނީންނަށް) އެއުރެން (އެބަހީ: އިންސީން) ކާފިރުކަމާއި ބޮޑާކަން އިތުރުކުރޫއެވެ.","",""],["","","","وأنهم ظنوا كما ظننتم أن لن يبعث الله أحدا","އަދި ތިޔަބައިމީހުން (އެބަހީ: ޖިންނީން) ހީކުރިފަދައިން އެއުރެންވެސް (އެބަހީ: އިންސީންވެސް) ހީކުރީ، ﷲ، އެއްވެސް މީހަކު އަލުން ދިރުމަކަށް ނުފޮނުއްވާނެކަމަށެވެ.","",""],["","","","وأنا لمسنا السماء فوجدناها ملئت حرسا شديدا وشهبا","އަދި ތިމަންމެން އުޑުގެ ޚަބަރު ހޯދަން އުޅުނީމުއެވެ. ފަހެ، ތިމަންމެންނަށް އެތަންފެނުނީ، ބަލަހައްޓަވާ، ގަދަފަދަ މަލާއިކަތްނާއި، ގިނިހިލަތަކުން ފުރިފައިވާތީއެވެ.","",""],["","","","وأنا كنا نقعد منها مقاعد للسمع فمن يستمع الآن يجد له شهابا رصدا","އަދި ތިމަންމެން އެ އުޑުގެ ތަންތަނުގައި އަޑުއަހަން އިށީނދެ ތިބޭކަމުގައިވީމުއެވެ. ފަހެ، މިހާރު އެ އަޑު އަހަންއުޅޭމީހަކަށް ފެންނަހުށީ ފާރަލައިގެންވާ ގިނިހިލަޔެކެވެ.","",""],["","","","وأنا لا ندري أشر أريد بمن في الأرض أم أراد بهم ربهم رشدا","އަދި ބިމުގައިވާ މީހުންނަށް އިރާދަކުރައްވާފައިވަނީ، ނުބަޔަކަށްކަން، ނުވަތަ އެއުރެންގެ ވެރިރަސްކަލާނގެ، އެއުރެންނަށް އިރާދަކުރައްވާފައިވަނީ، ތެދުމަގަކަށްކަން ތިމަންމެންނަކަށް ނޭނގެތެވެ.","",""],["","","","وأنا منا الصالحون ومنا دون ذلك كنا طرائق قددا","އަދި ތިމަންމެންގެ ތެރެއިން ހެޔޮލަފާ މީހުންނާއި، އެނޫން މީހުންވެއެވެ. ތިމަންމެންވަނީ، ތަފާތު ބައިބަޔަށެވެ.","",""],["","","","وأنا ظننا أن لن نعجز الله في الأرض ولن نعجزه هربا","އަދި ތިމަންމެންނަށް ބިމުގައި ﷲ ނުކުޅައްދައި ނުލެވޭނެކަމާއި، އަދި އެކަލާނގެއަށް ފިލައިގެން ދިޔުމުގައިވެސް ނުކުޅައްދައި ނުލެވޭނެކަން ތިމަންމެން ޔަގީންކުރަމުއެވެ.","",""],["","","","وأنا لما سمعنا الهدى آمنا به فمن يؤمن بربه فلا يخاف بخسا ولا رهقا","އަދި ތިމަންމެން ތެދުމަގުގެ އަޑު (އެބަހީ: ގުރްއާންގެއަޑު) އެހިހިނދު، ތިމަންމެން އެއަށް އީމާން ވެއްޖައީމުއެވެ. ފަހެ، އެމީހެއްގެ ވެރިރަސްކަލާނގެއަށް އީމާންވާ މީހާ (ދަންނާށެވެ!) ފަހެ، ދަރުމަ އުނިކުރައްވައިފާނެކަމަކަށް، އަދި އަނިޔާލިބިދާނެކަމަކަށް އެމީހާ ބިރެއްނުގަންނާނެތެވެ.","",""],["","","","وأنا منا المسلمون ومنا القاسطون فمن أسلم فأولئك تحروا رشدا","އަދި ތިމަންމެންގެ ތެރެއިން މުސްލިމު ންވެއެވެ. އަދި ތިމަންމެންގެ ތެރެއިން ތެދުމަގުން އެއްކިބާވެފައިވާ މީހުންވެއެވެ. ފަހެ، އިސްލާމްވި މީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެން ތެދުމަގު އިޚްތިޔާރު ކޮށްފޫއެވެ.","",""],["","","","وأما القاسطون فكانوا لجهنم حطبا","އަދި ތެދުމަގުން އެއްކިބާވި މީހުން ދަންނާށެވެ! ފަހެ، ނަރަކައިގެ ދަރު ކަމުގައި އެއުރެންވޫއެވެ.","",""],["","","","وأن لو استقاموا على الطريقة لأسقيناهم ماء غدقا","އެއުރެން ތެދުމަގުގައި ސީދާވެ ތިބެއްޖެނަމަ، ތިމަންރަސްކަލާނގެ، ހަމަކަށަވަރުން، އެއުރެންނަށް ގިނަވެގެންވާ ފެން (އެބަހީ: ރިޒްގު ތަނަވަސްކުރެއްވުން) ދެއްވާހުށީމެވެ.","",""],["","","","لنفتنهم فيه ومن يعرض عن ذكر ربه يسلكه عذابا صعدا","(އެއީ) ތިމަންރަސްކަލާނގެ، އެއުރެން އެކަމުގައި އިމްތިހާނުކުރެއްވުމަށްޓަކައެވެ. އަދި އެމީހާގެ ވެރިރަސްކަލާނގެ ހަނދުމަކުރުމުން އެއްކިބާވެއްޖެ މީހާ (ދަންނާށެވެ!) ގަދަފަދަވެގެންވާ އަޒާބަކަށް އެކަލާނގެ އެމީހާ ވައްދަވާހުށްޓެވެ.","",""],["","","","وأن المساجد لله فلا تدعوا مع الله أحدا","އަދި މިސްކިތްތައް ވަނީ ﷲއަށެވެ. ފަހެ، ތިޔަބައިމީހުން ﷲއާއެކު އެހެން އެއްވެސް ފަރާތަކަށް އަޅުކަން ނުކުރާހުށިކަމެވެ!","",""],["","","","وأنه لما قام عبد الله يدعوه كادوا يكونون عليه لبدا","އަދި ﷲގެ އަޅާ، އެކަލާނގެއަށް އަޅުކަން ކުރެއްވުމަށް ތެދުވެވަޑައިގަތްހިނދު (އެ ޖިންނީންގެ) ޖަމާއަތްތައް އެކަލޭގެފާނުގެ އަރިހަށް (އެކަލޭގެފާނު ކިޔަވައި ވިދާޅުވާ އަޑު އެހުމަށް) ބޮނޑިވެގަތުމާ ގާތްވޫއެވެ.","",""],["","","","قل إنما أدعو ربي ولا أشرك به أحدا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިމަންކަލޭގެފާނު އަޅުކަންކުރައްވާކަން ކަށަވަރީ، ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށެވެ. އަދި ތިމަންކަލޭގެފާނު އެއްވެސް ފަރާތެއް އެކަލާނގެއާ ޝަރީކެއް ނުކުރައްވަމެވެ.","",""],["","","","قل إني لا أملك لكم ضرا ولا رشدا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށް ގެއްލުމެއް ދިނުމެއްވެސް، އަދި ތެދުމަގެއް ދެއްކުމެއްވެސް، ތިމަންކަލޭގެފާނަކަށް މިލްކުވެގެނެއް ނުވެތެވެ.","",""],["","","","قل إني لن يجيرني من الله أحد ولن أجد من دونه ملتحدا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! (ތިމަންކަލޭގެފާނު އުރެދިއްޖެނަމަ) ހަމަކަށަވަރުން، ﷲގެ އަޒާބުން، ތިމަންކަލޭގެފާނު މިންޖުކުރާނޭ ހަމައެކަކުވެސް ނުވެތެވެ. އަދި އެކަލާނގެ ފިޔަވައި ސަލާމަތްވުމަށްދާނޭ އެހެންފަރާތެއް ތިމަންކަލޭގެފާނަކަށް ފެނިވަޑައެއް ނުގަންނަވާނެތެވެ.","",""],["","","","إلا بلاغا من الله ورسالاته ومن يعص الله ورسوله فإن له نار جهنم خالدين فيها أبدا","އެހެނެއްކަމަކު (ތިމަންކަލޭގެފާނަށްއޮތީ) ﷲގެ ހަޒުރަތުން އަންގަވާ އެންގެވުމަކާއި، އެކަލާނގެ ރިސާލަތްތައް އިއްވެވުމެވެ. ﷲއަށާއި، އެކަލާނގެ ރަސޫލާއަށް އުރެދޭ މީހާ (ދަންނާށެވެ!) ފަހެ، ހަމަކަށަވަރުން، އެމީހަކަށްހުރީ، ނަރަކައިގެ އަލިފާނެވެ. އެތާނގައި އެއުރެން އަބަދަށް ދެމިތިބެނިވި ގޮތުގައެވެ.","",""],["","","","حتى إذا رأوا ما يوعدون فسيعلمون من أضعف ناصرا وأقل عددا","އެއުރެންނަށް ވައުދުކުރައްވާފައިވާ އަޒާބު ފެނިއްޖައުމަށް ދާނދެނެވެ. ފަހެ، އެހިނދު ނަސްރު ދޭ މީހުންގެ ގޮތުން ނިކަމެތި، އަދި އަދަދުގެގޮތުން މަދީ ކޮންބަޔެއްކަން ނިކަންހުރެ އެއުރެންނަށް އެނގޭނެތެވެ.","",""],["","","","قل إن أدري أقريب ما توعدون أم يجعل له ربي أمدا","ކަލޭގެފާނު ވިދާޅުވާށެވެ! ތިޔަބައިމީހުންނަށް ވައުދުކުރައްވާ އަޒާބު ގާތްވެއްޖެކަމެއްވެސް، ނުވަތަ ތިމަންކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެކަމަކަށް ދިގުމުއްދަތެއް ލައްވާނެކަމެއްވެސް ތިމަންކަލޭގެފާނަކަށް އެނގިވަޑައެއް ނުގަނެތެވެ.","",""],["","","","عالم الغيب فلا يظهر على غيبه أحدا","(އެކަލާނގެއީ) ޣައިބު ދެނެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ. ފަހެ، އެކަލާނގެ ޣައިބެއްވެސް މީހަކަށް ފާޅެއްނުކުރައްވަތެވެ.","",""],["","","","إلا من ارتضى من رسول فإنه يسلك من بين يديه ومن خلفه رصدا","އެކަލާނގެ ރުހިވޮޑިގެންވާ ރަސޫލަކަށް މެނުވީއެވެ. ފަހެ، ހަމަކަށަވަރުން، އެކަލާނގެ އެ ރަސޫލެއްގެ ކުރިފުޅުމަތިންނާއި، ފަހަތްޕުޅުން ބަލަހައްޓަވާ މަލާއިކަތުން ފޮނުއްވަތެވެ.","",""],["","","","ليعلم أن قد أبلغوا رسالات ربهم وأحاط بما لديهم وأحصى كل شيء عددا","(އެއީ) އެބޭކަލުންގެ ވެރިރަސްކަލާނގެ ރިސާލަތްތައް އެބޭކަލުން އިއްވެވިކަން ދެނެވޮޑިގެންވެ، އެކަން ހާމަވުމަށްޓަކައެވެ. އަދި އެބޭކަލުންގެ މެދުގައި ވާހާ ކަމެއް އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަދި އެކަލާނގެ ހުރިހާ އެއްޗެއްގެ އަދަދު ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","بسم الله الرحمن الرحيم يا أيها المزمل","އޭ ފޭރާންތައް (ގައިކޮޅުގައި) އޮޅުއްވައިގެން އޮންނެވި ކަލޭގެފާނެވެ!","",""],["","","","قم الليل إلا قليلا","ރޭގަނޑުގެ އަޅުކަން ކުރެއްވުމަށް ތެދުވެވަޑައިގަންނަވާށެވެ! ވަރަށްކުޑަ ވަގުތުކޮޅަކަށް މެނުވީއެވެ.","",""],["","","","نصفه أو انقص منه قليلا","އެ ރޭގަނޑުގެ ދެބައިކުޅަ އެއްބައިގައެވެ. ނުވަތަ އެޔަށްވުރެ ކުޑަތަންކޮޅެއް އުނިކޮށްލައްވާށެވެ!","",""],["","","","أو زد عليه ورتل القرآن ترتيلا","ނުވަތަ އެޔަށްވުރެ އިތުރުކޮށްލައްވާށެވެ! އަދި ލަސްލަހުން ގުރްއާން ކިޔަވައި ވިދާޅުވާށެވެ!","",""],["","","","إنا سنلقي عليك قولا ثقيلا","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނުގެ މައްޗަށް ބަރުދަންހުރި ބަހެއް ބާވައިލައްވާހުށީމެވެ.","",""],["","","","إن ناشئة الليل هي أشد وطئا وأقوم قيلا","ހަމަކަށަވަރުން، ނިދުމަށްފަހު، ރޭއަޅުކަންކުރުމަށް ތެދުވުން ބުރަކަން ބޮޑެވެ. އަދި ބަސްތައް (އެބަހީ: ނަމާދުގެ ތެރޭގައި ކިޔަވާ ކިޔެވުންތައް) ސީދާކަން ބޮޑެވެ.","",""],["","","","إن لك في النهار سبحا طويلا","ހަމަކަށަވަރުން، ކަލޭގެފާނަށް ދުވާލުގެ ވަގުތުގައި ގިނަ މަސައްކަތްތަކެއް ވެއެވެ.","",""],["","","","واذكر اسم ربك وتبتل إليه تبتيلا","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އިސްމުފުޅު ހަނދުމަކުރައްވާށެވެ! އަދި (އެހެންހުރިހާ ފަރާތަކުން އެއްކިބާވެ، ހަމައެކަނި) އެކަލާނގެ ހަޒުރަތަށް އިހްލާސް ތެރިކަމާއެކު ކުއްތަންވެވަޑައިގަންނަވާށެވެ!","",""],["","","","رب المشرق والمغرب لا إله إلا هو فاتخذه وكيلا","(އެއީ) މަޝްރިގާއި، މަޣްރިބުގެ ވެރިރަސްކަލާނގެއެވެ. އެކަލާނގެ ފިޔަވައި އެހެން އިލާހަކު ނުވެއެވެ. ފަހެ، ވަކީލަކު ކަމުގައި ކަލޭގެފާނު އެކަލާނގެ ޚިޔާރުކުރައްވާށެވެ!","",""],["","","","واصبر على ما يقولون واهجرهم هجرا جميلا","އަދި އެއުރެން ބުނާ ބަސްތަކަށް ކަލޭގެފާނު ކެތްކުރައްވާށެވެ! އަދި ރިވެތިވެގެންވާ ވަކިވުމަކުން، ކަލޭގެފާނު އެއުރެންނާ ވަކިވެވަޑައިގަންނަވާށެވެ!","",""],["","","","وذرني والمكذبين أولي النعمة ومهلهم قليلا","އަދި ފައިސާވެރި، ދޮގުކުރާމީހުން، ކަލޭގެފާނު ތިމަންރަސްކަލާނގެއަށް ދޫކޮށްލައްވާށެވެ! އަދި ކަލޭގެފާނު ކުޑަވަގުތުކޮޅަކަށް އެއުރެންނަށް މުހުލަތް ދެއްވާށެވެ!","",""],["","","","إن لدينا أنكالا وجحيما","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ހަޒުރަތުގައި ކަސްތަޅުތަކާއި ނަރަކަވެއެވެ.","",""],["","","","وطعاما ذا غصة وعذابا أليما","އަދި ކަރުގައި އަޅައިގަންނަ ކާނާއާއި، ވޭންދެނިވި އަޒާބު ވެސްމެއެވެ.","",""],["","","","يوم ترجف الأرض والجبال وكانت الجبال كثيبا مهيلا","އެދުވަހުން ބިމާއި، ފަރުބަދަތައް ހެލިގެންދާނެތެވެ. އަދި ފައިބައިގެންދާ ވެލިފުންޏަކަށް އެ ފަރުބަދަތައް ވާހުށްޓެވެ.","",""],["","","","إنا أرسلنا إليكم رسولا شاهدا عليكم كما أرسلنا إلى فرعون رسولا","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ މައްޗަށް ހެކިވެވަޑައިގަންނަވާ ބޭކަލެއްކަމުގައި، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންގެ ގާތަށް ރަސޫލަކު ފޮނުއްވީމެވެ. ފިރްޢައުނުގެގާތަށް ތިމަންރަސްކަލާނގެ ރަސޫލަކު ފޮނުއްވި ފަދައިންނެވެ.","",""],["","","","فعصى فرعون الرسول فأخذناه أخذا وبيلا","ފަހެ، ފިރްޢައުނު، ރަސޫލާއަށް އުރެދުނެވެ. ދެން ތިމަންރަސްކަލާނގެ ގަދަފަދަވެގެންވާ އަޒާބުގެ ހިއްޕެވުމަކުން ހިއްޕަވައި، އެ ފިރްޢައުނު ހަލާކުކުރެއްވީމެވެ.","",""],["","","","فكيف تتقون إن كفرتم يوما يجعل الولدان شيبا","ފަހެ، ތިޔަބައިމީހުން ކާފިރު ވެއްޖެނަމަ (އެދުވަހުގެ ބިރުވެރިކަމުން) ކުޑަކުދިން މުސްކުޅިންނަށް ހަދައިލާ ދުވަހުން (އެބަހީ: އެދުވަހުގެ އަޒާބުން) ތިޔަބައިމީހުން ރައްކާތެރިވާނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","السماء منفطر به كان وعده مفعولا","އެދުވަހުން އުޑު އިރައިރައިގެން ދާނެތެވެ. އެކަލާނގެ ވައުދުފުޅު ފުރިހަމަވާނެކަން ޔަގީނެވެ.","",""],["","","","إن هذه تذكرة فمن شاء اتخذ إلى ربه سبيلا","ހަމަކަށަވަރުން، މިއީ ހަނދާންކޮށްދިނުމެކެވެ. ފަހެ، (ހަނދާންކުރުމަށް) އެދޭމީހާ، އެމީހާގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް މަގެއް ހިފާހުށިކަމެވެ!","",""],["","","","إن ربك يعلم أنك تقوم أدنى من ثلثي الليل ونصفه وثلثه وطائفة من الذين معك والله يقدر الليل والنهار علم أن لن تحصوه فتاب عليكم فاقرءوا ما تيسر من القرآن علم أن سيكون منكم مرضى وآخرون يضربون في الأرض يبتغون من فضل الله وآخرون يقاتلون في سبيل الله فاقرءوا ما تيسر منه وأقيموا الصلاة وآتوا الزكاة وأقرضوا الله قرضا حسنا وما تقدموا لأنفسكم من خير تجدوه عند الله هو خيرا وأعظم أجرا واستغفروا الله إن الله غفور رحيم","ކަލޭގެފާނާއި، ކަލޭގެފާނުގެ އަރިހުގައިވާ މީހުންކުރެ ބަޔަކު، ރޭގަނޑުގެ ތިންބައިކުޅަ ދެބަޔަށްވުރެ މަދުންނާއި، އެ ރޭގަނޑުގެ ދެބައިކުޅަ އެއްބައިގައާއި، އަދި އެ ރޭގަނޑުގެ ތިންބައިކުޅަ އެއްބައިގައި، ރޭއަޅުކަން ކުރެއްވުމަށް ތިއްބަވާކަން ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. އަދި ރޭގަނޑާއި، ދުވާލުގެ ވަގުތުތައް މިންވަރު ކުރައްވަނީ ﷲއެވެ. މުޅި ރޭގަނޑު، ރޭއަޅުކަމުގައި ގާއިމުވެ ތިބުމަށް ތިޔަބައިމީހުންނަށް ކުޅަދާނަވެގެން ނުވާނެކަން އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. ފަހެ، ތިޔަބައިމީހުންގެ މައްޗަށް އެކަން އަފޫކުރައްވައި ލުއިކުރައްވައިފިއެވެ. ފަހެ، ގުރްއާނުން ފަސޭހަވީ މިންވަރެއް ތިޔަބައިމީހުން ކިޔަވާށެވެ! ތިޔަބައިމީހުންގެ ތެރެއިން ބަލިމީހުން ވާނޭކަމާއި، އަދި އަނެއްބަޔަކު ﷲގެ ފަޟްލު ވަންތަކަން އެދިގެން ބިމުގައި ދަތުރުފަތުރުކުރާކަމާއި، އަދި އަނެއްބަޔަކު ﷲގެ މަގުގައި ހަނގުރާމަ ކުރާކަން އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ. ފަހެ، އެ ގުރްއާނުން ފަސޭހަވީ މިންވަރެއް ތިޔަބައިމީހުން ކިޔަވާށެވެ! އަދި ތިޔަބައިމީހުން ނަމާދު ގާއިމުކުރާށެވެ! އަދި ތިޔަބައިމީހުން ޒަކާތް ދޭށެވެ! އަދި ރިވެތިވެގެންވާ ދަރަނިދިނުމަކުން ތިޔަބައިމީހުން ﷲއަށް ދަރަނިދޭށެވެ! (އެބަހީ: ﷲއަށްޓަކައި ހޭދަކުރާށެވެ!) އަދި ހެޔޮކަމުގެ ތެރެއިން، ތިޔަބައިމީހުންގެ އަމިއްލަ ނަފްސު ތަކަށްޓަކައި އިސްކުރާ ކޮންމެ ކަމެއްގެ ސަވާބު، ﷲގެ ހަޒުރަތުގައި ހެޔޮކަން ބޮޑުވެގެންވާތީއާއި، އަދި ދަރުމަ ބޮޑުވެގެންވާތީ ތިޔަބައިމީހުންނަށް ފެންނާނެތެވެ. އަދި ތިޔަބައިމީހުން ﷲގެ ހަޒުރަތުން ފާފަފުއްސެވުމަށް އެދޭށެވެ! ހަމަކަށަވަރުން، ﷲއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ރަޙީމްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم يا أيها المدثر","އޭ ފޭރާންތައް (ގައިކޮޅުގައި) އޮޅުއްވައިގެން އޮންނެވި ކަލޭގެފާނެވެ!","",""],["","","","قم فأنذر","ކަލޭގެފާނު ތެދުވެވަޑައިގެން އިންޒާރުކުރައްވާށެވެ!","",""],["","","","وربك فكبر","އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް ތަކްބީރު ވިދާޅުވާށެވެ!","",""],["","","","وثيابك فطهر","އަދި ކަލޭގެފާނުގެ ފޭރާންކޮޅުތައް ތާހިރުކުރައްވާށެވެ!","",""],["","","","والرجز فاهجر","އަދި ބުދަށް އަޅުކަންކުރުމާ ދުރުވެވަޑައިގަންނަވާށެވެ!","",""],["","","","ولا تمنن تستكثر","އަދި ގިނައިން ލިބުން އެދިވަޑައިގެން (މީހަކަށް) އެއްޗެއް ނުދެއްވާށެވެ!","",""],["","","","ولربك فاصبر","އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށްޓަކައި ކަލޭގެފާނު ކެތްތެރިވެ ވަޑައިގަންނަވާށެވެ!","",""],["","","","فإذا نقر في الناقور","ފަހެ، ތާޅަފިލި ފުމެލައްވާ ހިނދެވެ.","",""],["","","","فذلك يومئذ يوم عسير","ފަހެ، އެދުވަސް އެއީ އުނދަގޫވެގެންވާ ދުވަހެކެވެ.","",""],["","","","على الكافرين غير يسير","ކާފިރުންގެ މައްޗަށް ފަސޭހަކަމެއް ނުވާ ދުވަހެކެވެ.","",""],["","","","ذرني ومن خلقت وحيدا","ހަމައެކަނި ތިމަންރަސްކަލާނގެ ހެއްދެވި މީހާ، ކަލޭގެފާނު ތިމަންރަސްކަލާނގެއަށް ދޫކޮށްލައްވާށެވެ!","",""],["","","","وجعلت له مالا ممدودا","އަދި ގިނަވެގެންވާ މުދަލާއި ކައިރީގައި ތިބޭނެ ފިރިހެންދަރިން، ތިމަންރަސްކަލާނގެ އޭނާޔަށް ދެއްވީމެވެ.","",""],["","","","وبنين شهودا","އަދި ގިނަވެގެންވާ މުދަލާއި ކައިރީގައި ތިބޭނެ ފިރިހެންދަރިން، ތިމަންރަސްކަލާނގެ އޭނާޔަށް ދެއްވީމެވެ.","",""],["","","","ومهدت له تمهيدا","އަދި (ދުނިޔޭގެ ހުރިހާ ކަމެއް) ތަނަވަސްކޮށްދެއްވައި، އޭނާޔަށް ފަސޭހަކޮށްދެއްވީމެވެ.","",""],["","","","ثم يطمع أن أزيد","ދެންވެސް އޭނާ އެދެނީ، ތިމަންރަސްކަލާނގެ އިތުރުކޮށްދެއްވުމަށެވެ.","",""],["","","","كلا إنه كان لآياتنا عنيدا","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ހަމަކަށަވަރުން، އޭނާވީ، ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް ދެކޮޅުހަދާ މީހެއް ކަމުގައެވެ.","",""],["","","","سأرهقه صعودا","ނިކަންހުރެ ތިމަންރަސްކަލާނގެ، ގަދަފަދަވެގެންވާ އަޒާބަކަށް ކުރިމަތިލުމަށް އޭނާއަށް ޖައްސަވާހުށީމެވެ.","",""],["","","","إنه فكر وقدر","ހަމަކަށަވަރުން، އޭނާ ވިސްނައި ފިކުރު ކޮށް ރޭވިއެވެ.","",""],["","","","فقتل كيف قدر","ފަހެ، އޭނާޔަށް ލައުނަތް ލެއްވިއެވެ. އޭނާ ރޭވީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","ثم قتل كيف قدر","ދެން އޭނާޔަށް ލައުނަތް ލެއްވިއެވެ. އޭނާ ރޭވީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","ثم نظر","ދެން އޭނާ ބަލައި ވިސްނިއެވެ.","",""],["","","","ثم عبس وبسر","ދެން އޭނާ މޫނު ކުނިކޮށްލިއެވެ. އަދި މޫނު ހެދިއެވެ.","",""],["","","","ثم أدبر واستكبر","ދެން އޭނާ ފުރަގަސްދިނެވެ. އަދި ބޮޑާވެގަތެވެ.","",""],["","","","فقال إن هذا إلا سحر يؤثر","ފަހެ، އޭނާ ބުންޏެވެ. ޖާދޫގަރުންގެ ކިބައިން އައިސްފައިވާ ޖާދޫއެއް ކަމުގައި މެނުވީ މި ގުރްއާން ނުވެއެވެ.","",""],["","","","إن هذا إلا قول البشر","އާދަމުގެދަރިންގެ ބަސްކަމުގައި މެނުވީ މި ގުރްއާން ނުވެއެވެ.","",""],["","","","سأصليه سقر","ނިކަންހުރެ ތިމަންރަސްކަލާނގެ އޭނާ ނަރަކަޔަށް ވައްދަވާހުށީމެވެ.","",""],["","","","وما أدراك ما سقر","އެ ނަރަކަޔަކީ ކޮންއެއްޗެއްކަން ކަލޭގެފާނަށް އަންގައިދިނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","لا تبقي ولا تذر","އެ ނަރަކަ (ނާންދާ) އެއްވެސް އެއްޗެއް ނުބަހައްޓަތެވެ. އަދި ދޫކޮށެއްވެސް ނުލަތެވެ.","",""],["","","","لواحة للبشر","ގައިގެ ހަން އަންދައި ކަޅުކޮށްލަތެވެ.","",""],["","","","عليها تسعة عشر","(ބެލެހެއްޓެވުމަށް) އެ ނަރަކައިގެ މައްޗަށް އޮނަވިހި މަލާއިކަތް ންވެއެވެ.","",""],["","","","وما جعلنا أصحاب النار إلا ملائكة وما جعلنا عدتهم إلا فتنة للذين كفروا ليستيقن الذين أوتوا الكتاب ويزداد الذين آمنوا إيمانا ولا يرتاب الذين أوتوا الكتاب والمؤمنون وليقول الذين في قلوبهم مرض والكافرون ماذا أراد الله بهذا مثلا كذلك يضل الله من يشاء ويهدي من يشاء وما يعلم جنود ربك إلا هو وما هي إلا ذكرى للبشر","އަދި ނަރަކައިގެ ބަނޑޭރިން ކަމުގައި، ތިމަންރަސްކަލާނގެ މަލާއިކަތުން މެނުވީ ނުލައްވަމެވެ. އަދި ކާފިރުވި މީހުންނަށް އިމްތިހާނެއްކަމުގައި މެނުވީ އެ މަލާއިކަތުންގެ އަދަދު ނުލައްވަމެވެ. (އެއީ) ފޮތް ލިބުނު މީހުންނަށް ޔަގީން ވުމަށާއި، އަދި އީމާންވި މީހުންގެ އީމާން ކަން އިތުރުވުމަށާއި، އަދި ފޮތް ލިބުނު މީހުންނާއި އީމާންވި މީހުން ޝައްކު ނުކުރުމަށްޓަކައެވެ. އަދި އެއުރެންގެ ހިތްތަކުގައި ބަލިމަޑުކަމެއްވާ މީހުންނާއި، ކާފިރުން ބުނުމަށްޓަކައެވެ. މި މިސާލުން ﷲ އިރާދަކުރެއްވީ ކޮންއެއްޗެއް ބާވައެވެ؟ އެފަދައިން ﷲ އިރާދަކުރައްވާ މީހަކު މަގުފުރައްދަވަތެވެ. އަދި އެކަލާނގެ އިރާދަކުރައްވާ މީހަކަށް ތެދުމަގު ދައްކަވަތެވެ. އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ލަޝްކަރުގެ އަދަދު، އެކަލާނގެ މެނުވީ ދެނެވޮޑިގެން ނުވެތެވެ. އަދި އާދަމުގެދަރިންނަށް އިބްރަތް ތެރި ހަނދާންކޮށްދިނުމެއް ކަމުގައި މެނުވީ، އެ ނަރަކަ ނުވެތެވެ.","",""],["","","","كلا والقمر","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ހަނދު ގަންދެއްވަމެވެ.","",""],["","","","والليل إذ أدبر","އަދި ރޭގަނޑު ފަސްދީދާހިނދު، އެ ރޭގަނޑު ގަންދެއްވަމެވެ.","",""],["","","","والصبح إذا أسفر","އަދި އަލިވެގެންދާހިނދު، ފަތިސް ގަންދެއްވަމެވެ.","",""],["","","","إنها لإحدى الكبر","ހަމަކަށަވަރުން، އެ ނަރަކައީ، ބޮޑެތި ބަލާތަކުގެ ތެރެއިން ބަލާއެއްކަން ކަށަވަރެވެ.","",""],["","","","نذيرا للبشر","އާދަމުގެދަރިންނަށް އިންޒާރުކުރާ އެއްޗެއްގެ ގޮތުގައެވެ.","",""],["","","","لمن شاء منكم أن يتقدم أو يتأخر","ތިޔަބައިމީހުންކުރެ ބޭނުން މީހަކަށް ކުރިއެރުންވެއެވެ. ނުވަތަ ފަސްޖެހުންވެއެވެ.","",""],["","","","كل نفس بما كسبت رهينة","ކޮންމެ ނަފްސެއް، އެ ނަފްސެއް ހޯދައިގަތްކަމަކުން ބަނދެވިގެންވެއެވެ.","",""],["","","","إلا أصحاب اليمين","ކަނާތްފަރާތުގެ އަހުލުވެރިން މެނުވީއެވެ.","",""],["","","","في جنات يتساءلون","(އެއުރެންވަނީ) ސުވަރުގެތަކެއްގައެވެ. ކުށްވެރިންނާ މެދުގައި އެކަކު އަނެކަކާ ސުވާލުކުރާ ޙާލު ގައެވެ.","",""],["","","","عن المجرمين","(އެއުރެންވަނީ) ސުވަރުގެތަކެއްގައެވެ. ކުށްވެރިންނާ މެދުގައި އެކަކު އަނެކަކާ ސުވާލުކުރާ ޙާލު ގައެވެ.","",""],["","","","ما سلككم في سقر","ތިޔަބައިމީހުން ނަރަކަޔަށް ވެއްދީ ކޮންކަމެއް ހެއްޔެވެ؟","",""],["","","","قالوا لم نك من المصلين","އެއުރެން ބުނާނެތެވެ. ނަމާދުކުރާ މީހުންގެ ތެރެޔަކު ތިމަންމެން ނުވަމުއެވެ.","",""],["","","","ولم نك نطعم المسكين","އަދި ތިމަންމެން މިސްކީނުންނަށް ކާންދީއެއް ނޫޅެމުއެވެ.","",""],["","","","وكنا نخوض مع الخائضين","އަދި ބާތިލު ވާހަކަ ދައްކާ މީހުންނާ އެކުގައި، ތިމަންމެން ބާތިލު ވާހަކަ ދައްކައި އުޅުނީމުއެވެ.","",""],["","","","وكنا نكذب بيوم الدين","އަދި ތިމަންމެން ގިޔާމަތް ދުވަސް ދޮގުކޮށް އުޅުނީމުއެވެ.","",""],["","","","حتى أتانا اليقين","ޔަގީން ކަން (އެބަހީ: މަރު) ތިމަންމެންނާ ހަމަޔަށް އަތުވެއްޖައުމަށް ދާނދެނެވެ.","",""],["","","","فما تنفعهم شفاعة الشافعين","ފަހެ، ޝަފާއަތް ތެރިވާމީހުންގެ ޝަފާއަތް، އެއުރެންނަކަށް މަންފާއެއް ނުކުރާނެތެވެ.","",""],["","","","فما لهم عن التذكرة معرضين","ފަހެ، ހަނދާންކޮށްދިނުމުން (އެބަހީ: ގުރްއާނުން) އެއުރެން އެއްކިބާވެ ދުރަށްދަނީ ކީއްވެގެން ހެއްޔެވެ؟","",""],["","","","كأنهم حمر مستنفرة","އެއުރެން ސިންގާއަކަށް ފިލަންދުވާ ވަޙުޝީ ހިމާރު ތަކެއް ފަދައެވެ.","",""],["","","","فرت من قسورة","އެއުރެން ސިންގާއަކަށް ފިލަންދުވާ ވަޙުޝީ ހިމާރު ތަކެއް ފަދައެވެ.","",""],["","","","بل يريد كل امرئ منهم أن يؤتى صحفا منشرة","އަދި ކިއެއްތަ! އެއުރެންކުރެ ކޮންމެ މީހަކު އެދެނީ، ލިޔުއްވާފައިވާ ފަތްފުށްތަކެއް އެމީހަކަށް ބާވައިލެއްވުމަށެވެ.","",""],["","","","كلا بل لا يخافون الآخرة","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. އަދި ކިއެއްތަ! އެއުރެން އާޚިރަތަކަށް ބިރެއް ނުގަނެތެވެ.","",""],["","","","كلا إنه تذكرة","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ހަމަކަށަވަރުން، އެ ގުރްއާނަކީ ހަނދާންކޮށްދިނުމެކެވެ.","",""],["","","","فمن شاء ذكره","ފަހެ، ބޭނުން މީހަކު އެ ގުރްއާން ހަނދުމަކުރާހުށިކަމެވެ!","",""],["","","","وما يذكرون إلا أن يشاء الله هو أهل التقوى وأهل المغفرة","އަދި ﷲ އިރާދަކުރެއްވިއްޔާ މެނުވީ، އެއުރެންނަކަށް ހަނދާނެއް ނުކުރެވޭނެތެވެ. އެކަލާނގެއީ (މީސްތަކުން އެކަލާނގެއަށް ބިރުވެތިވެ) ތަގުވާވެރިވުން ހައްގު ވެގެންވާ، އަދި (ކިޔަމަންގަތް އަޅުންނަށް) ފާފަތައް ފުއްސެވުމުގެ ވެރިރަސްކަލާނގެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم لا أقسم بيوم القيامة","ގިޔާމަތް ދުވަސް ގަންދެއްވައި ހުވާ ވަހީކުރައްވަމެވެ.","",""],["","","","ولا أقسم بالنفس اللوامة","އަދި އައްނަފްސުއްލައްވާމާ ގަންދެއްވައި ހުވާ ވަހީކުރައްވަމެވެ. (ނޯޓު: އައްނަފްސުއްލައްވާމާއަކީ، ނުބައިކަންތައް ކުރާކަމުގެ މައްޗަށާއި، ހެޔޮކަންތައް ނުކުރާކަމުގެ މައްޗަށް، އަމިއްލަ ނަފްސަށް މަލާމާތް ރައްދުކޮށްކޮށް ހުންނަ ނަފްސެކެވެ.)","",""],["","","","أيحسب الإنسان ألن نجمع عظامه","އިންސާނާ ހީކުރަނީ، ތިމަންރަސްކަލާނގެ އޭނާގެ ކަށިތައް އެއްނުކުރައްވާނެ ކަމަށްހެއްޔެވެ؟","",""],["","","","بلى قادرين على أن نسوي بنانه","އެހެންނަކުން ނޫނެވެ. އެ އިންސާނާގެ އިނގިލިތަކުގެ ކުރިތައް ހަމަކުރެއްވުމަށްވެސް، ތިމަންރަސްކަލާނގެ ކުޅަދުންވަންތައެވެ.","",""],["","","","بل يريد الإنسان ليفجر أمامه","އަދި ކިއެއްތަ! އިންސާނާ އެދެނީ، އޭނާގެ ކުރިޔަށް އޮތްތާނގައިވެސް ފާފަތައް ކޮށްއުޅުމަށެވެ.","",""],["","","","يسأل أيان يوم القيامة","އޭނާ ސުވާލުކުރާނެތެވެ. ގިޔާމަތް ދުވަސް އަންނާނީ ކޮންއިރަކުން ހެއްޔެވެ؟","",""],["","","","فإذا برق البصر","ފަހެ، ލޯތަކަށް ހައިރާން ކަންލިބި، ތަރަތަރަލާހިނދެވެ.","",""],["","","","وخسف القمر","އަދި ހަނދުގެ އަލިކަން ފިލައިދާހިނދެވެ.","",""],["","","","وجمع الشمس والقمر","އަދި އިރާއި، ހަނދު އެއްތަންކުރައްވާހިނދެވެ.","",""],["","","","يقول الإنسان يومئذ أين المفر","އެދުވަހުން އިންސާނާ ބުނާނެތެވެ. ފިލަންދާނީ ކޮންތާކަށް ހެއްޔެވެ؟","",""],["","","","كلا لا وزر","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ރައްކާވެ ތިބެންދާނެ ތަނެއްނެތެވެ.","",""],["","","","إلى ربك يومئذ المستقر","އެދުވަހުންގޮސް ހަމަޖެހުންވަނީ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","ينبأ الإنسان يومئذ بما قدم وأخر","އިންސާނާ އިސްކުޅަހާ ކަމަކާއި، ފަސްކުޅަހާ ކަމެއްގެ ވާހަކައިން އެ އިންސާނާއަށް އެދުވަހުން ޚަބަރު ދެއްވާނެތެވެ.","",""],["","","","بل الإنسان على نفسه بصيرة","އަދި ކިއެއްތަ! އެ އިންސާނާވަނީ އޭނާގެ އަމިއްލަ ނަފްސުގެ މައްޗަށްވާ ހެތްކެއް ކަމުގައެވެ.","",""],["","","","ولو ألقى معاذيره","އެ އިންސާނާ، އޭނާގެ އުޒުރުތައް ކުރިމަތިކުޅަނަމަވެސް މެއެވެ.","",""],["","","","لا تحرك به لسانك لتعجل به","އެ ގުރްއާން ލިބިވަޑައިގަތުން އަވަސްކުރެއްވުމަށް ކަލޭގެފާނުގެ ދޫފުޅު، އެ ގުރްއާނާއިގެން ޙަރަކާތް ތެރި ނުކުރައްވާށެވެ!","",""],["","","","إن علينا جمعه وقرآنه","ހަމަކަށަވަރުން، އެ ގުރްއާން (ކަލޭގެފާނުގެ ހިތްޕުޅަށް) ޖަމަޢުކުރެއްވުމާއި، އަދި އެ ގުރްއާން ކިޔަވައިވިދާޅުވުމުގެ ކުޅަދާނަކަން ދެއްވުމަކީ، ތިމަންރަސްކަލާނގެއަށް އޮތްކަމެކެވެ.","",""],["","","","فإذا قرأناه فاتبع قرآنه","ފަހެ، ތިމަންރަސްކަލާނގެ (ޖިބްރީލުގެފާނު މެދުވެރިކުރައްވައި) އެ ގުރްއާން ކިޔަވައިދެއްވާހިނދު، ފަހެ، ކަލޭގެފާނު އެ ކިޔަވައިދެއްވުމާ ތަބާ ވެވަޑައިގަންނަވާށެވެ!","",""],["","","","ثم إن علينا بيانه","ދެން ހަމަކަށަވަރުން، އެ ގުރްއާން ބަޔާންކޮށްދެއްވުން ވަނީވެސް ތިމަންރަސްކަލާނގެއަށެވެ.","",""],["","","","كلا بل تحبون العاجلة","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. އަދި ކިއެއްތަ! ތިޔަބައިމީހުން ލޯބިކުރަނީ ދުނިޔޭގެ ކަންތަކަށެވެ.","",""],["","","","وتذرون الآخرة","އަދި ތިޔަބައިމީހުން އާޚިރަތް ދޫކޮށްލަމުއެވެ.","",""],["","","","وجوه يومئذ ناضرة","އެދުވަހުން މޫނުތަކެއް ރީތިވެ، އަލިވެގެންވެއެވެ.","",""],["","","","إلى ربها ناظرة","އެ މޫނުތަކުގެ ވެރިރަސްކަލާނގެއަށް ބަލަބަލައި ތިބެއެވެ.","",""],["","","","ووجوه يومئذ باسرة","އަދި އެދުވަހުން މޫނުތަކެއް ހުތުރުވެ، މޮޅިވެގެންވެއެވެ.","",""],["","","","تظن أن يفعل بها فاقرة","މައިކަށީގެ ބަދަތައް ބިނދޭވަރުގެކަމެއް ކުރެވޭނެކަމަށް (އެ މޫނުތަކުގެ ވެރިން) ހީކުރެތެވެ.","",""],["","","","كلا إذا بلغت التراقي","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ވައިނޮޅިކަށިގަނޑާ ހަމަޔަށް ފުރާނަ ފޯރައްޖެހިނދެވެ.","",""],["","","","وقيل من راق","އަދި އަންގަވާހިނދެވެ. ފަންޑިތައެއް ހަދައި، ފަރުވާއެއް ކުރާނީ ކާކުހެއްޔެވެ؟","",""],["","","","وظن أنه الفراق","އަދި އެއީ ވަކިވުން ކަމުގައި ޔަގީން ކޮށްފި ހިނދެވެ.","",""],["","","","والتفت الساق بالساق","އަދި (މަރުގެ ސަކަރާތުގައި) އެއްފައި އަނެއްފަޔާ އޮޅައިލެވޭހިނދެވެ.","",""],["","","","إلى ربك يومئذ المساق","އެދުވަހުން އެމީހަކު ގެންދެވުންވަނީ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","فلا صدق ولا صلى","ފަހެ، އޭނާ (ﷲގެ ފޮތް) ތެދެއްވެސް ނުކުރެތެވެ. އަދި ނަމާދެއްވެސް ނުކުރެތެވެ.","",""],["","","","ولكن كذب وتولى","އެހެނެއްކަމަކު އޭނާ ދޮގުކުރިއެވެ. އަދި އޭނާ ފުރަގަސްދީ އެނބުރިދިޔައެވެ.","",""],["","","","ثم ذهب إلى أهله يتمطى","ދެން އޭނާގެ އަހުލުވެރިންގެ ގާތަށް ބޮޑާކަންމަތީ ހިނގަމުންދިޔައެވެ.","",""],["","","","أولى لك فأولى","ކަލެޔަށް ހަލާކު ހުށްޓެވެ. ފަހެ، (ކަލެޔަށް) ހަލާކު ހުށްޓެވެ.","",""],["","","","ثم أولى لك فأولى","ދެންވެސް ކަލެޔަށް ހަލާކު ހުށްޓެވެ. ފަހެ، (ކަލެޔަށް) ހަލާކު ހުށްޓެވެ.","",""],["","","","أيحسب الإنسان أن يترك سدى","ބޭކާރުގޮތުގައި އޭނާ ދޫކޮށްލައްވާނެކަމަށް އިންސާނާ ހީކުރަނީ ހެއްޔެވެ؟","",""],["","","","ألم يك نطفة من مني يمنى","އޮހޮރައިލެވޭ މަނީގެ ތިއްކެއް ކަމުގައި އޭނާ ނުވޭހެއްޔެވެ؟","",""],["","","","ثم كان علقة فخلق فسوى","ދެން ގަނޑުލޭކޮޅެއް ކަމުގައި އޭނާ ވިއެވެ. ފަހެ، އެކަލާނގެ އެ އިންސާނާ ހައްދަވައި، ފުރިހަމަކުރެއްވިއެވެ.","",""],["","","","فجعل منه الزوجين الذكر والأنثى","ފަހެ، އޭނާގެ ކިބައިން، ފިރިހެން އަންހެން ދެބާވަތް އުފެއްދެވިއެވެ.","",""],["","","","أليس ذلك بقادر على أن يحيي الموتى","އެކަން އެގޮތަށް ކުރެއްވި ރަސްކަލާނގެ، މަރުވެފައިވާ މީހުން އަލުން ދިރުއްވުމަށް ކުޅަދުންވަންތަވެވޮޑިގެން ނުވޭހެއްޔެވެ؟","",""],["","","","بسم الله الرحمن الرحيم هل أتى على الإنسان حين من الدهر لم يكن شيئا مذكورا","ނަންގަނެވިގެންވާ އެއްޗެއްކަމުގައި އިންސާނާ ނުވާ ޒަމާންތަކެއް، އެ އިންސާނާގެ މައްޗަށް އައިކަން ކަށަވަރެވެ.","",""],["","","","إنا خلقنا الإنسان من نطفة أمشاج نبتليه فجعلناه سميعا بصيرا","ހަމަކަށަވަރުން، އެއްކުރައްވާފައިވާ މަނިތިއްކަކުން، ތިމަންރަސްކަލާނގެ އިންސާނާ ހެއްދެވީމެވެ. (އެއީ) އޭނާ އިމްތިހާނުކުރެއްވުމަށްޓަކައެވެ. ފަހެ، ކަންފަތަށް އިވޭ، ލޮލަށް ފެންނަ މީހަކު ކަމުގައި ތިމަންރަސްކަލާނގެ އޭނާ ލެއްވީމެވެ.","",""],["","","","إنا هديناه السبيل إما شاكرا وإما كفورا","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އޭނާޔަށް މަގުދެއްކެވީމެވެ. (އެއީ) އޭނާ ޝުކުރުވެރިވުމަށްޓަކައެވެ. ނޫނީ އޭނާ ދެކޮޅުވެރިވެ، ކާފިރު ވުމަށްޓަކައެވެ.","",""],["","","","إنا أعتدنا للكافرين سلاسل وأغلالا وسعيرا","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކާފިރުންނަށްޓަކައި ހިލިހިލާތަކާއި، ކަސްތޮޅުތަކާއި، އަނދައަނދާ ހުންނަ ނަރަކަ، ތައްޔާރުކުރެއްވީމެވެ.","",""],["","","","إن الأبرار يشربون من كأس كان مزاجها كافورا","ހަމަކަށަވަރުން، ހެޔޮލަފާ މީހުން ރާތަށްޓަކުން ބޯނެތެވެ. އެއާ އެއްކުރައްވާފައިވާ އެއްޗަކީ، ކާފޫރުކަމުގައިވިއެވެ.","",""],["","","","عينا يشرب بها عباد الله يفجرونها تفجيرا","އެއީ ﷲގެ (ހެޔޮލަފާ) އަޅުން އެއިން ބުއިމަށްވާ ފެންއާރެކެވެ. އެއުރެން ބޭނުންގޮތަކަށް އެއިން ފެންއަރުވާނެތެވެ.","",""],["","","","يوفون بالنذر ويخافون يوما كان شره مستطيرا","އެއުރެން ނަދުރު ފުއްދަތެވެ. އަދި އެދުވަހެއްގެ ނުރައްކާތެރިކަން ފެތުރިގެންދާ ދުވަހަކަށް (އެބަހީ: ގިޔާމަތް ދުވަހަށް) އެއުރެން ބިރުވެތިވެތެވެ.","",""],["","","","ويطعمون الطعام على حبه مسكينا ويتيما وأسيرا","އަދި އެތަކެއްޗަށް ލޯބި ހުރުމާއެކުވެސް، މިސްކީންނާއި، ޔަތީމްނާއި، ހައްޔަރުވެފައިވާ މީހުންނަށް އެއުރެން ކާތަކެތި ކާންދެތެވެ.","",""],["","","","إنما نطعمكم لوجه الله لا نريد منكم جزاء ولا شكورا","(ބުނަމުންނެވެ.) ތިމަންމެން ތިޔަބައިމީހުންނަށް ކާންދޭކަން ކަށަވަރީ، ﷲގެ ވަޖުހު ފުޅަށްޓަކައެވެ. ތިޔަބައިމީހުންގެ ކިބައިން އެކަމުގެ އުޖޫރައެއް، އަދި ޝުކުރެއްވެސް ތިމަންމެން ނޭދެމުއެވެ.","",""],["","","","إنا نخاف من ربنا يوما عبوسا قمطريرا","ހަމަކަށަވަރުން، އެދުވަހެއްގައި، މޫނުތައް ގަދަފަދަގޮތެއްގައި ފުސްވެގެންވާ ދުވަހަކާމެދު، ތިމަންމެންގެ ވެރިރަސްކަލާނގެއަށް ތިމަންމެން ބިރުވެތިވަމުއެވެ.","",""],["","","","فوقاهم الله شر ذلك اليوم ولقاهم نضرة وسرورا","ފަހެ، އެދުވަހުގެ ނުބައިކަމުން ﷲ، އެއުރެން ރައްކާތެރި ކުރެއްވިއެވެ. އަދި މޫނު އަލިކަމާއި، އުފާވެރިކަން އެއުރެންނަށް ދެއްވިއެވެ.","",""],["","","","وجزاهم بما صبروا جنة وحريرا","އެއުރެން ކެތްތެރިވިކަމަށްޓަކައި، ޖަޒާއެއްގެ ގޮތުގައި އެއުރެންނަށް ސުވަރުގެއާއި، ފަށުއި ފޭރާން ދެއްވިއެވެ.","",""],["","","","متكئين فيها على الأرائك لا يرون فيها شمسا ولا زمهريرا","އެތާނގައި އެއުރެން ދާންތަކުގެ މަތީގައި ލެނގިލައިގެން ތިބޭ ޙާލު ގައެވެ. އެތާނގައި އަވީގެ ހޫނެއް، ނުވަތަ ގަދަފިންޏެއްވިޔަސް އެއުރެން ނުދެކޭނެތެވެ.","",""],["","","","ودانية عليهم ظلالها وذللت قطوفها تذليلا","އެތާނގެ ގަސްގަހުގެ ހިޔާތައް، އެއުރެންނަށް ގާތްވެގެންވެއެވެ. އަދި ގަސްގަހުގެ މޭވާތައް ބިނުމަށް ފަހިކުރައްވައި ފަސޭހަކުރައްވާފައިވެއެވެ.","",""],["","","","ويطاف عليهم بآنية من فضة وأكواب كانت قواريرا","އަދި ރިހިންވާ ކަންވާރުތަކާއި، ފެންބޯ ތަށިތަކާއިގެން އެއުރެންގެ މެދުގައި ބުރުޖެހޭނެތެވެ. އެ ތަކެތި ބިއްލޫރި ފަދައިންވެއެވެ.","",""],["","","","قوارير من فضة قدروها تقديرا","ރިހީގެ ބިއްލޫރި ތަކެކެވެ. އެއުރެން އަދަދު ކޮށް، އެ ތަކެތި މިންވަރު ކުރާނެތެވެ. (އެބަހީ: އެ ތަށިތަކުގެ ބޮޑުކުޑަމިނާއި އެ ތަށިތަށްޓަށް އަޅާފައިވާ ތަކެތި، އެއުރެން ބޭނުންގޮތަކަށް ކަނޑައަޅާނެތެވެ.)","",""],["","","","ويسقون فيها كأسا كان مزاجها زنجبيلا","އަދި އެތާނގައި އެއުރެންނަށް ރާތަށްޓެއް ބުއިމަށް ދެއްވާނެތެވެ. އެއާ އެއްކުރައްވާފައިވާ އެއްޗެއްކަމުގައި ވަނީ، ޒަންޖަބީލެވެ.","",""],["","","","عينا فيها تسمى سلسبيلا","(އެއީ) އެތާނގައިވާ ސަލްސަބީލު އޭ ނަމަކަށް ކިޔޭ އާރެކެވެ.","",""],["","","","ويطوف عليهم ولدان مخلدون إذا رأيتهم حسبتهم لؤلؤا منثورا","އަދި ޒުވާންކަންމަތީ ދެމިތިބޭ ޒުވާން ފިރިހެންކުދިން، އެއުރެންގެ ޚިދުމަތުގައި ބުރުޖަހާނެތެވެ. ތިބާޔަށް އެކުދިން ފެނިއްޖެނަމަ، އެކުދިންނީ، އެތަންމިތަނަށް ވިހުރުވައިލާފައިވާ ރަން މުތްތަކެއްހެން ތިބާޔަށް ހީވާނެތެވެ.","",""],["","","","وإذا رأيت ثم رأيت نعيما وملكا كبيرا","އަދި ތިބާޔަށް އެތަން ފެނިއްޖެނަމަ (ސިފަނުކުރެވޭފަދަ) ނިއުމަތާއި، ބޮޑުވެގެންވާ ވެރިކަމެއް ތިބާޔަށް އެތަނުން ފެންނާނެތެވެ.","",""],["","","","عاليهم ثياب سندس خضر وإستبرق وحلوا أساور من فضة وسقاهم ربهم شرابا طهورا","ފެހިކުލައިގެ ސުންދުސް ފޭރާމާއި، އިސްތަބްރަގު ފޭރާމުން އެއުރެންގައި ފޭރާން ލައްވާނެތެވެ. އަދި ރިހި އުޅާތަކުން އެއުރެން ގަހަނާ އަޅުއްވާނެތެވެ. އަދި އެއުރެންގެ ވެރިރަސްކަލާނގެ، އެއުރެންނަށް ސާފު ތާހިރު ބުއިމެއް ބޯންދެއްވާނެތެވެ.","",""],["","","","إن هذا كان لكم جزاء وكان سعيكم مشكورا","(އަދި އެއުރެންނަށް އަންގަވާނެތެވެ.) ހަމަކަށަވަރުން، މިކަންތައްވަނީ، ތިޔަބައިމީހުންނަށް (ހެޔޮ) ޖަޒާއެއް ކަމުގައެވެ. އަދި ތިޔަބައިމީހުންކުޅަ މަސައްކަތަކީ، ޝުކުރު ލިބެނިވި ކަމެއްކަމުގައި ވެއެވެ.","",""],["","","","إنا نحن نزلنا عليك القرآن تنزيلا","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނުގެ މައްޗަށް ގުރްއާން ވަކިވަކިކޮށް ބާވައިލެއްވީމެވެ.","",""],["","","","فاصبر لحكم ربك ولا تطع منهم آثما أو كفورا","ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހުކުމް ފުޅަށް، ކަލޭގެފާނު ކެތްތެރިވެވަޑައިގަންނަވާށެވެ! އަދި އެއުރެންގެ ތެރެއިން ފާފަވެރިޔަކަށް، ނުވަތަ ކާފިރަކަށް ކަލޭގެފާނު ކިޔަމަންވެވަޑައިނުގަންނަވާށެވެ!","",""],["","","","واذكر اسم ربك بكرة وأصيلا","އަދި ހެނދުނާއި، ހަވީރު، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އިސްމުފުޅު ހަނދުމަކުރައްވާށެވެ!","",""],["","","","ومن الليل فاسجد له وسبحه ليلا طويلا","އަދި ރޭގަނޑުން ބައެއްގައި، އެކަލާނގެއަށް ކަލޭގެފާނު ސަޖިދަކުރައްވާށެވެ! އަދި ރޭގަނޑުގެ ދިގު ވަގުތުތަކުގައި، ކަލޭގެފާނު އެކަލާނގެއަށް ތަސްބީހަ ވިދާޅުވާށެވެ!","",""],["","","","إن هؤلاء يحبون العاجلة ويذرون وراءهم يوما ثقيلا","ހަމަކަށަވަރުން، މިބައިމީހުން ދުނިޔޭގެ ދިރިއުޅުމަށް ލޯބިކުރެތެވެ. އަދި ބަރުދަންހުރި ދުވަހެއް އެއުރެންގެ ފަހަތަށް ދޫކޮށްލަތެވެ.","",""],["","","","نحن خلقناهم وشددنا أسرهم وإذا شئنا بدلنا أمثالهم تبديلا","ތިމަންރަސްކަލާނގެ އެއުރެން ހެއްދެވީމެވެ. އަދި އެއުރެންގެ ހެއްދެވުން ވަރުގަދަކުރެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ އިރާދަކުރައްވައިފިނަމަ، އެއުރެންފަދަ އެހެންބަޔަކު ގެންނަވައި، ފުރިހަމަޔަށް އެއުރެން ބަދަލުކުރައްވައިފީމުހެވެ.","",""],["","","","إن هذه تذكرة فمن شاء اتخذ إلى ربه سبيلا","ހަމަކަށަވަރުން، މި ގުރްއާނަކީ، ހަނދާންކޮށްދިނުމެކެވެ. ފަހެ، ބޭނުންމީހަކު، އެމީހާގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް މަގެއް ހިފައިފާހުށިކަމެވެ.","",""],["","","","وما تشاءون إلا أن يشاء الله إن الله كان عليما حكيما","އަދި ﷲ އިރާދަކުރެއްވުމުން މެނުވީ، ތިޔަބައިމީހުންނަކަށް (އެއްވެސްކަމެއް) ނޭދެވޭނެތެވެ. ހަމަކަށަވަރުން، މޮޅަށް ދެނެވޮޑިގެންވާ، ޙަކީމްވަންތަ ރަސްކަލާނގެ ކަމުގައި ﷲ ވޮޑިގެންވެއެވެ.","",""],["","","","يدخل من يشاء في رحمته والظالمين أعد لهم عذابا أليما","އެކަލާނގެ އިރާދަކުރައްވާ މީހަކު، އެކަލާނގެ ރަހުމަތްގެ ތެރެޔަށް ވައްދަވަތެވެ. އަދި އަނިޔާވެރިންނަށްޓަކައި، ވޭންދެނިވި އަޒާބު އެކަލާނގެ ތައްޔާރުކުރައްވާފައިވެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم والمرسلات عرفا","ވިދިވިދިގެން އަންނަ ވައިރޯޅިތަކާއި،","",""],["","","","فالعاصفات عصفا","އަދި ގަދަޔަށް އަންނަ ބާރު ވައިރޯޅިތަކާއި،","",""],["","","","والناشرات نشرا","އަދި ވިލާތައް ފަރާތްފަރާތަށް ފަތުރާ ވައިރޯޅިތަކާއި،","",""],["","","","فالفارقات فرقا","ހައްގާއި ބާތިލު ވަކިކުރާ (ގުރްއާންގެ) އާޔަތް ތަކާއި،","",""],["","","","فالملقيات ذكرا","އަދި ހަނދުމަކޮށްދޭ އާޔަތްތައް (ރަސޫލުންނަށް) ގެނެސްދެއްވާ މަލާއިކަތުން ގަންދެއްވަމެވެ.","",""],["","","","عذرا أو نذرا","އުޒުރު ނެތިކުރެއްވުމަށާއި، އިންޒާރުކުރެއްވުމަށެވެ.","",""],["","","","إنما توعدون لواقع","ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނަށް ވައުދުކުރައްވާ ކަންތަކީ، ވާނޭކަންތައްކަން ކަށަވަރެވެ.","",""],["","","","فإذا النجوم طمست","ފަހެ، ތަރިތަކުން އޭގެ އަލިކަން ފުއްސަވައިފިހިނދެވެ.","",""],["","","","وإذا السماء فرجت","އަދި އުޑު ފަޅައިގެން ހިނގައްޖެހިނދެވެ.","",""],["","","","وإذا الجبال نسفت","އަދި ފަރުބަދަތައް ކުނޑިކުނޑިވެގެން ހިނގައްޖެހިނދެވެ.","",""],["","","","وإذا الرسل أقتت","އަދި ރަސޫލުން ކަނޑައެޅިގެންވާ ވަގުތަށް އެއްކުރައްވައިފިހިނދެވެ.","",""],["","","","لأي يوم أجلت","އެކަންތައްތައް ފަސްކުރައްވާފައިވަނީ، ކޮންދުވަހަކަށް ހެއްޔެވެ؟","",""],["","","","ليوم الفصل","ނިޔާކުރައްވާ ދުވަހަށެވެ.","",""],["","","","وما أدراك ما يوم الفصل","އަދި ނިޔާކުރައްވާ ދުވަހަކީ، ކޮންދުވަހެއްކަން ކަލޭގެފާނަށް އަންގައިދިނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","ويل يومئذ للمكذبين","ދޮގުކުރާ މީހުންނަށް އެދުވަހުން ގެއްލުމާއި ހަލާކު ހުށްޓެވެ.","",""],["","","","ألم نهلك الأولين","ތިމަންރަސްކަލާނގެ، އިސްވެދިޔަ މީހުން ހަލާކު ނުކުރައްވަންހެއްޔެވެ؟","",""],["","","","ثم نتبعهم الآخرين","ދެން ތިމަންރަސްކަލާނގެ އެއުރެންގެ ފަހަތުން ފަހުގެ މީހުން ގެންދަވާހުށީމެވެ.","",""],["","","","كذلك نفعل بالمجرمين","ކުށްވެރިންނާމެދު، ތިމަންރަސްކަލާނގެ ކަންތައް ކުރައްވަނީ އެފަދައިންނެވެ.","",""],["","","","ويل يومئذ للمكذبين","ދޮގުކުރާ މީހުންނަށް އެދުވަހުން ގެއްލުމާއި، ހަލާކު ހުށްޓެވެ.","",""],["","","","ألم نخلقكم من ماء مهين","ދެރަވެގެންވާ ފެނަކުން (އެބަހީ: މަނިފޮދަކުން) ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން ނަހައްދަވަން ހެއްޔެވެ؟","",""],["","","","فجعلناه في قرار مكين","ފަހެ، ރައްކާތެރިވެގެންވާ ތަނެއްގައި، (އެބަހީ: ރަޙިމުގައި) ތިމަންރަސްކަލާނގެ އެ ފެން ލެއްވީމެވެ.","",""],["","","","إلى قدر معلوم","އެނގިގެންވާ މުއްދަތަކަށެވެ.","",""],["","","","فقدرنا فنعم القادرون","ފަހެ، ތިމަންރަސްކަލާނގެ (އެހުރިހާކަމެއް) މިންވަރު ކުރެއްވީމެވެ. ފަހެ، މިންވަރުކުރައްވާ ކަލާނގެ މޮޅުކަމާއެވެ!","",""],["","","","ويل يومئذ للمكذبين","ދޮގުކުރާ މީހުންނަށް އެދުވަހުން ގެއްލުމާއި ހަލާކުހުށްޓެވެ.","",""],["","","","ألم نجعل الأرض كفاتا","ދިރިތިބި މީހުންނާއި، މަރުވެފައިވާ މީހުން އެތަނަށް އެއްކުރައްވާނެ ތަނެއް ކަމުގައި، ތިމަންރަސްކަލާނގެ ބިން ނުލައްވަން ހެއްޔެވެ؟","",""],["","","","أحياء وأمواتا","ދިރިތިބި މީހުންނާއި، މަރުވެފައިވާ މީހުން އެތަނަށް އެއްކުރައްވާނެ ތަނެއް ކަމުގައި، ތިމަންރަސްކަލާނގެ ބިން ނުލައްވަން ހެއްޔެވެ؟","",""],["","","","وجعلنا فيها رواسي شامخات وأسقيناكم ماء فراتا","އަދި ތިމަންރަސްކަލާނގެ އެ ބިމުގައި ހަރުލައިހުންނަ އުސްފަރުބަދަތައް ލެއްވީމެވެ. އަދި ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް މީރުފެން ބޯންދެއްވީމެވެ.","",""],["","","","ويل يومئذ للمكذبين","ދޮގުކުރާ މީހުންނަށް އެދުވަހުން ގެއްލުމާއި ހަލާކު ހުށްޓެވެ.","",""],["","","","انطلقوا إلى ما كنتم به تكذبون","(އެއުރެންނަށް އަންގަވާނެތެވެ.) ތިޔަބައިމީހުން ދޮގުކޮށްއުޅުނު ކަންތަކަށް ތިޔަބައިމީހުން ހިނގައިދާށެވެ!","",""],["","","","انطلقوا إلى ظل ذي ثلاث شعب","ތިންކަތްޕަށް ކަފިވެފައިވާ ހިޔަންޏެއްގެ ތެރެޔަށް (އެބަހީ: ނަރަކައިގެ އަލިފާންގަނޑުގެ ދުމުގެ ތެރެޔަށް) ތިޔަބައިމީހުން ހިނގައިދާށެވެ!","",""],["","","","لا ظليل ولا يغني من اللهب","(އެއިން) ހިޔަލެއްވެސް ނުދެތެވެ. އަދި ހުޅުގަނޑުގެ ހޫނުން ސަލާމަތްކޮށެއްވެސް ނުމެދޭމެއެވެ.","",""],["","","","إنها ترمي بشرر كالقصر","ހަމަކަށަވަރުން، ބޮޑެތި ގަނޑުވަރުފަދަ ކަނިތައް، އެ ހުޅުގަނޑު އުކައެވެ.","",""],["","","","كأنه جمالت صفر","އެ ކަނިތައް، ރީނދޫކުލައިގެ ޖަމަލު ތަކެއް ފަދައެވެ.","",""],["","","","ويل يومئذ للمكذبين","ދޮގުކުރާ މީހުންނަށް އެދުވަހުން ގެއްލުމާއި ހަލާކު ހުށްޓެވެ.","",""],["","","","هذا يوم لا ينطقون","މިއީ އެއުރެންނަށް ބަސްނުމޮށެވޭނޭ ދުވަހެވެ.","",""],["","","","ولا يؤذن لهم فيعتذرون","އަދި އެއުރެން އުޒުރު ދެއްކުމަކަށް، އެއުރެންނަކަށް އިޛުނެއް ނުމެދެއްވާނޭމެއެވެ.","",""],["","","","ويل يومئذ للمكذبين","ދޮގުކުރާ މީހުންނަށް އެދުވަހުން ގެއްލުމާއި، ހަލާކު ހުށްޓެވެ.","",""],["","","","هذا يوم الفصل جمعناكم والأولين","(ވަހީކުރައްވާނެތެވެ.) މިއީ ނިޔާކުރެއްވުމުގެ ދުވަހެވެ. ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނާއި، އަދި ކުރީގެ މީހުން އެއްކުރެއްވީމެވެ.","",""],["","","","فإن كان لكم كيد فكيدون","ފަހެ، ތިޔަބައިމީހުންނަށް ހަދާނޭ ޙީލަތެއް ލިބިގެންވާނަމަ، ފަހެ، ތިމަންރަސްލާނގެއާމެދު ތިޔަބައިމީހުން ޙީލަތް ހަދައިބަލާށެވެ!","",""],["","","","ويل يومئذ للمكذبين","ދޮގުކުރާ މީހުންނަށް އެދުވަހުން ގެއްލުމާއި، ހަލާކު ހުށްޓެވެ.","",""],["","","","إن المتقين في ظلال وعيون","ހަމަކަށަވަރުން، ތަގުވާވެރިންވަނީ، ހިޔާތަކާއި، ފެން އާރުތަކުގެ ނިއުމަތް ގައެވެ.","",""],["","","","وفواكه مما يشتهون","އަދި އެއުރެން ހިތްއެދޭ މޭވާތަކުގެ ތެރޭގައެވެ.","",""],["","","","كلوا واشربوا هنيئا بما كنتم تعملون","(އަދި އަންގަވާނެތެވެ.) ތިޔަބައިމީހުން ކޮށްއުޅުނު ޢަމަލުތަކުގެ ސަބަބުން، އަރާމު ލިބެނިވިގޮތުގައި ތިޔަބައިމީހުން ކައިބޮއި އުޅޭށެވެ!","",""],["","","","إنا كذلك نجزي المحسنين","އިހްސާން ތެރިންނަށް ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ޖަޒާ ދެއްވަނީ އެފަދައިންނެވެ.","",""],["","","","ويل يومئذ للمكذبين","ދޮގުކުރާ މީހުންނަށް އެދުވަހުން ގެއްލުމާއި، ހަލާކު ހުށްޓެވެ.","",""],["","","","كلوا وتمتعوا قليلا إنكم مجرمون","(ދުނިޔޭގައި) ކުޑަހިނދުކޮޅަކަށް ތިޔަބައިމީހުން ކައި، އަރާމުކޮށް އުޅޭށެވެ! ހަމަކަށަވަރުން، ތިޔަބައިމީހުންނީ، ކުށްވެރިންނެވެ.","",""],["","","","ويل يومئذ للمكذبين","ދޮގުކުރާ މީހުންނަށް އެދުވަހުން ގެއްލުމާއި، ހަލާކު ހުށްޓެވެ.","",""],["","","","وإذا قيل لهم اركعوا لا يركعون","ތިޔަބައިމީހުން (ނަމާދުކޮށް) ރުކޫއު ކޮށްއުޅޭށޭ އެއުރެންނަށް ބުނެފިނަމަ، އެއުރެން ރުކޫއު ކޮށެއް ނޫޅެތެވެ.","",""],["","","","ويل يومئذ للمكذبين","ދޮގުކުރާ މީހުންނަށް އެދުވަހުން ގެއްލުމާއި، ހަލާކުހުށްޓެވެ.","",""],["","","","فبأي حديث بعده يؤمنون","ފަހެ، އެ ގުރްއާނަށްފަހު، އެއުރެން އީމާން ވަނީ، ކޮން ވާހަކައަކަށް ހެއްޔެވެ؟","",""],["","","","بسم الله الرحمن الرحيم عم يتساءلون","އެއުރެން އެކަކު އަނެކަކާ ސުވާލު ކޮށް އުޅެނީ، ކޮންކަމަކާ މެދުގައި ހެއްޔެވެ؟","",""],["","","","عن النبإ العظيم","ބޮޑުވެގެންވާ ޚަބަރާ މެދުގައެވެ.","",""],["","","","الذي هم فيه مختلفون","އެ ޚަބަރަކީ، އެއުރެން އެއާމެދު ޚިލާފު ވެގެންވާ ޚަބަރެވެ.","",""],["","","","كلا سيعلمون","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ނިކަންހުރެ އެއުރެންނަށް އެނގޭނެތެވެ.","",""],["","","","ثم كلا سيعلمون","ދެންވެސް ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ނިކަންހުރެ އެއުރެންނަށް އެނގޭނެތެވެ.","",""],["","","","ألم نجعل الأرض مهادا","ތަންމައްޗެއް ކަމުގައި، ތިމަންރަސްކަލާނގެ ބިން ނުލައްވަންހެއްޔެވެ؟","",""],["","","","والجبال أوتادا","އަދި (ބިން ހިފެހެއްޓުމަށްވާ) ކަޑަތަކެއް ކަމުގައި، ތިމަންރަސްކަލާނގެ ފަރުބަދަތައް ނުލައްވަންހެއްޔެވެ؟","",""],["","","","وخلقناكم أزواجا","އަދި (ދެ ޖިންސުން) ޖޯޑުޖޯޑަށް ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުން ހެއްދެވީމެވެ.","",""],["","","","وجعلنا نومكم سباتا","އަދި ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންގެ ނިދި، އަރާމެއް ކަމުގައި ލެއްވީމެވެ.","",""],["","","","وجعلنا الليل لباسا","އަދި ފޭރާމެއް ކަމުގައި، ތިމަންރަސްކަލާނގެ ރޭގަނޑު ލެއްވީމެވެ.","",""],["","","","وجعلنا النهار معاشا","އަދި ދިރިއުޅުމަށް މަސައްކަތްކުރުމުގެ ވަގުތެއް ކަމުގައި، ތިމަންރަސްކަލާނގެ ދުވާލު ލެއްވީމެވެ.","",""],["","","","وبنينا فوقكم سبعا شدادا","ގަދަފަދަވެގެންވާ ހަތް އުޑު ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންގެ މަތީގައި ބިނާކުރެއްވީމެވެ.","",""],["","","","وجعلنا سراجا وهاجا","އަދި އަލިކަންގަދަ ވޮށެއް (އެބަހީ: އިރު) ތިމަންރަސްކަލާނގެ ލެއްވީމެވެ.","",""],["","","","وأنزلنا من المعصرات ماء ثجاجا","އަދި ވާރޭވިލާތަކުގެ ތެރެއިން އޮހިގެންއަންނަ ފެން، ތިމަންރަސްކަލާނގެ ބާވައިލެއްވީމެވެ.","",""],["","","","لنخرج به حبا ونباتا","އެ ފެނުގެ ސަބަބުން، އޮށްޓަރާއި، ފަތްޕިލާވެލި ފަޅުއްވައި، ނެރުއްވުމަށްޓަކައެވެ.","",""],["","","","وجنات ألفافا","އަދި ފަތްތައް ބޯކޮށް ހެދިފައިވާ ބަގީޗާތައް މެއެވެ.","",""],["","","","إن يوم الفصل كان ميقاتا","ހަމަކަށަވަރުން، ނިޔާކުރެއްވުމުގެ ދުވަސް ކަނޑައެޅިގެންވާ ދުވަހެއް ކަމުގައިވިއެވެ.","",""],["","","","يوم ينفخ في الصور فتأتون أفواجا","ތާޅަފިލި ފުމެލައްވާ ދުވަހުއެވެ. ފަހެ، އެދުވަހުން ތިޔަބައިމީހުން (މަހުޝަރު ބިމަށް) ބައިބަޔަށް އަންނާނޫއެވެ.","",""],["","","","وفتحت السماء فكانت أبوابا","އަދި އުޑުތައް ހުޅުއްވާނެތެވެ. ފަހެ، ދޮރޯށިތަކެއް ފަދައިން އެ އުޑުތައް ވާނެތެވެ.","",""],["","","","وسيرت الجبال فكانت سرابا","އަދި ފަރުބަދަތައް ލުހި، ފުނޑުފުނޑުވެގެންދާނެތެވެ. އަދި އެ ފަރުބަދަތައް އަވާމެންދުރެއް ކަމުގައި ވާނެތެވެ.","",""],["","","","إن جهنم كانت مرصادا","ހަމަކަށަވަރުން، ނަރަކައީ، އެތަނަކުން ކުށްވެރިންނަށް ބަލަބަލައިތިބޭ ތަނެއްކަމުގައިވެއެވެ.","",""],["","","","للطاغين مآبا","ކާފިރުންނަށް އެއުރެން އެނބުރިގޮސް ތިބޭނެތަނެއްގެ ގޮތުގައެވެ.","",""],["","","","لابثين فيها أحقابا","އެތައްޒަމާނަކަށް އެއުރެން އެތާނގައި، ލަސްވެތިބޭ ޙާލު ގައެވެ.","",""],["","","","لا يذوقون فيها بردا ولا شرابا","އެތާނގައި ފިނިކަމެއްގެ ރަހަވެސް، އަދި ބުއިމެއްގެ ރަހަވެސް އެއުރެންނަކަށް ނުލިބޭނެތެވެ.","",""],["","","","إلا حميما وغساقا","ކެކިކެކިހުންނަ ހޫނުފެނާއި (ނަރަކައިގެ އަހުލުވެރިންގެ) ގައިން އޮހޮރޭ ފާދިޔަ މެނުވީއެވެ.","",""],["","","","جزاء وفاقا","(އެއުރެންގެ ޢަމަލު ތަކާ) އެއްގޮތްވެގެންވާ ޖަޒާއެއްގެ ގޮތުންނެވެ.","",""],["","","","إنهم كانوا لا يرجون حسابا","ހަމަކަށަވަރުން ހިސާބު ބެއްލެވުމަށް ނޭދޭބަޔަކު ކަމުގައި އެއުރެންވޫއެވެ.","",""],["","","","وكذبوا بآياتنا كذابا","ބޮޑުވެގެންވާ ދޮގުކުރުމަކުން، ތިމަންރަސްކަލާނގެ އާޔަތްތައް އެއުރެން ދޮގުކުރޫއެވެ.","",""],["","","","وكل شيء أحصيناه كتابا","އަދި ކޮންމެ އެއްޗެއް ތިމަންރަސްކަލާނގެ ފޮތެއްގައި ހިމެނުއްވީމެވެ.","",""],["","","","فذوقوا فلن نزيدكم إلا عذابا","ފަހެ، ތިޔަބައިމީހުން (ކުޅަ ނުބައި ޢަމަލުތަކުގެ) ރަހަ ލިބިގަންނާށެވެ! ފަހެ، އަޒާބު މެނުވީ، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަކަށް އިތުރެއް ނުކުރައްވާ ހުށީމެވެ.","",""],["","","","إن للمتقين مفازا","ހަމަކަށަވަރުން، ތަގުވާވެރިންނަށް ހުރީ، ނަސީބު ލިބެނިވި ތަނެކެވެ.","",""],["","","","حدائق وأعنابا","ބަގީޗާތަކާއި، އަދި މޭބިސްކަދުރުތަކެވެ.","",""],["","","","وكواعب أترابا","އަދި އެއްފުރާވަރުގެ ޒުވާން އަންހެން ކުދިންނެވެ.","",""],["","","","وكأسا دهاقا","އަދި ފުރިފައިވާ ރާތަށިތަކެވެ.","",""],["","","","لا يسمعون فيها لغوا ولا كذابا","ބާތިލު ވާހަކަތަކެއް، އަދި ދޮގެއް އެއުރެން އެތާކު ނާހާނެތެވެ.","",""],["","","","جزاء من ربك عطاء حسابا","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން ލިބެނިވި ޖަޒާއެއްގެ ގޮތުގައެވެ. ފުދިގެންވާ ދެއްވުމެއްގެ ގޮތުގައެވެ.","",""],["","","","رب السماوات والأرض وما بينهما الرحمن لا يملكون منه خطابا","އުޑުތަކާއި، ބިމާއި، އެދެމެދުގައިވާހާ ތަކެއްޗެއްގެ ވެރި ރަޙްމާންވަންތަ ރަސްކަލާނގެ ހަޒުރަތުންނެވެ. އެކަލާނގެ ހަޒުރަތަށް ބަސްދެންނެވުމަށް އެއުރެންނަކަށް އެއްވެސްބާރެއް ލިބިގެނެއް ނުވެތެވެ.","",""],["","","","يوم يقوم الروح والملائكة صفا لا يتكلمون إلا من أذن له الرحمن وقال صوابا","ޖިބްރީލުގެފާނާއި، މަލާއިކަތުން ސަފަކަށް ގާއިމުވެ ތިއްބަވާ ދުވަހެވެ. ރަޙްމާންވަންތަ ރަސްކަލާނގެ، އެމީހަކަށް އިޒުނަ ދެއްވައި، ހައްގު ތެދުބަހެއް ބުނެފި މީހަކު މެނުވީ، އެކަކަށްވެސް ވާހަކައެއް ނުދެއްކޭނެތެވެ.","",""],["","","","ذلك اليوم الحق فمن شاء اتخذ إلى ربه مآبا","އެއީ ކަށަވަރުވެގެންވާ ދުވަހެވެ. ފަހެ، ބޭނުންމީހަކު އެމީހާގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ރުޖޫއަ ވުމެއް ހިފައިފާހުށިކަމެވެ!","",""],["","","","إنا أنذرناكم عذابا قريبا يوم ينظر المرء ما قدمت يداه ويقول الكافر يا ليتني كنت ترابا","ހަމަކަށަވަރުން، ގާތްވެގެންވާ އަޒާބެއްގެ ވާހަކައިން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް އިންޒާރުކުރެއްވީމެވެ. (އެއީ) އެމީހެއްގެ ދެއަތުން އިސްކޮށްފައިވާ ކަންތައް، އެމީހާ ދެކޭނޭ ދުވަހެވެ. އަދި ކާފިރުވި މީހާ ބުނާނެތެވެ. އޭ ސަހަރޯއެވެ! ތިމަން ވެއްޔަށްވީނަމަ، ކިހާ ރަނގަޅުވީސް ހެއްޔެވެ؟","",""],["","","","بسم الله الرحمن الرحيم والنازعات غرقا","ގަދަފަދަވެގެންވާ ގޮތުގައި (ކާފިރުންގެ) ފުރާނަތައް ގެންދަވާ މަލާއިކަތުން ގަންދެއްވަމެވެ.","",""],["","","","والناشطات نشطا","އަދި އޯގާވެރިކަމާއި، ފަސޭހަކަމާއެކު (މުއުމިނުންގެ) ފުރާނަތައް ގެންދަވާ މަލާއިކަތުން ގަންދެއްވަމެވެ.","",""],["","","","والسابحات سبحا","އަދި ކަލާނގެ އަމުރު ފުޅުތަކާއިގެން ދަތުރުކުރައްވާ މަލާއިކަތުން ގަންދެއްވަމެވެ.","",""],["","","","فالسابقات سبقا","އަދި (މުއުމިނުންގެ) ފުރާނަތަކާއިގެން ކުރިއަރައިދާ މަލާއިކަތުންނާއިއެވެ.","",""],["","","","فالمدبرات أمرا","އަދި (ދުނިޔޭގެ) ކަންތައްތައް ތަދްބީރުކުރެއްވުމުގައި އުޅުއްވާ މަލާއިކަތުންނާއިއެވެ.","",""],["","","","يوم ترجف الراجفة","(ތާޅަފިލި ފުރަތަމަފަހަރު ފުންމަވައިލެއްވުމުން) ބިންގަނޑު ހެލިގެންދާ ދުވަހެވެ.","",""],["","","","تتبعها الرادفة","އެއާ ވިދިގެން އޭގެފަހަތުން ދެވަނަ ފުންމެވުން ފުންމަވާ ދުވަހެވެ.","",""],["","","","قلوب يومئذ واجفة","އެދުވަހުން ބިރުގެންފައިވާ ހިތްތަކެއް ވެއެވެ.","",""],["","","","أبصارها خاشعة","އެއުރެންގެ ލޯތައް ތިރިވެ ނިކަމެތިވެގެންވެއެވެ.","",""],["","","","يقولون أإنا لمردودون في الحافرة","އެއުރެން ބުނެތެވެ. އިހުއުޅުނު ދުނިޔޭގެ ދިރިއުޅުމަށް، އަލުން ރައްދުކުރައްވާނޭ ބަޔަކު ކަމުގައި ހަމަކަށަވަރުން، ތިމަންމެން ވާނޭހެއްޔެވެ؟","",""],["","","","أإذا كنا عظاما نخرة","ފީވެ، އަޅިޔަށްވެފައިވާ ކަށިތަކެއް ކަމުގައި، ތިމަންމެން ވުމަށްފަހުގައިވެސް ހެއްޔެވެ؟","",""],["","","","قالوا تلك إذا كرة خاسرة","އެއުރެން ބުނޫއެވެ. އެހެންވިއްޔާ އެއީ، ގެއްލެނިވެގެންވާ އެނބުރި ދިޔުމެކެވެ.","",""],["","","","فإنما هي زجرة واحدة","ފަހެ، އެކަންތައްވާކަން ކަށަވަރީ، އެންމެ ފުމެލެއްވުމެއްގެ އަޑު ކަމުގައެވެ.","",""],["","","","فإذا هم بالساهرة","ފަހެ، އެހާރުން އެންމެން ތިބޭހުށީ، އަލުން ދިރި، މަހުޝަރު ބިމުގައެވެ.","",""],["","","","هل أتاك حديث موسى","މޫސާގެފާނުގެ ވާހަކަ ކަލޭގެފާނާ ހަމަޔަށް އައިސްފައިވޭތޯއެވެ؟","",""],["","","","إذ ناداه ربه بالواد المقدس طوى","ޠުވާ އޭ ކިޔުނު މުގައްދަސް ވާދީގައި ހުންނަވަނިކޮށް، އެކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، އެކަލޭގެފާނަށް ނިދާ އިއްވެވި ހިނދެވެ.","",""],["","","","اذهب إلى فرعون إنه طغى","ފިރްޢައުނުގެ ގާތަށް ކަލޭގެފާނު ވަޑައިގަންނަވާށެވެ! ހަމަކަށަވަރުން، ފުރެދުމުގައި އޭނާ ހައްދުފަހަނަޅައި ހިނގައްޖެއެވެ.","",""],["","","","فقل هل لك إلى أن تزكى","އަދި ކަލޭގެފާނު (އޭނާޔަށް) ވިދާޅުވާށެވެ! ކާފިރުކަމުން ތާހިރު ވެގަތުމަށް ކަލޭ އެދެމުހެއްޔެވެ؟","",""],["","","","وأهديك إلى ربك فتخشى","އަދި ކަލޭގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް އަހުރެން މަގު ދެއްކުމަށްވެސް މެއެވެ. އެއީ (އެކަލާނގެއަށް) ކަލޭ ބިރުވެތިވުމަށްޓަކައެވެ.","",""],["","","","فأراه الآية الكبرى","ފަހެ، އެކަލޭގެފާނު، އޭނާޔަށް ބޮޑުވެގެންވާ މުއުޖިޒާ ދެއްކެވިއެވެ.","",""],["","","","فكذب وعصى","ފަހެ، އޭނާ ދޮގުކުރިއެވެ. އަދި އުރެދުނެވެ.","",""],["","","","ثم أدبر يسعى","ދެން އޭނާ އެނބުރި، ފުރަގަސްދީ (ދެކޮޅުވެރިކަމުގެ) މަސައްކަތް ކުރަންފެށިއެވެ.","",""],["","","","فحشر فنادى","ފަހެ، (އޭނާގެ ލަޝްކަރު) އެއްކުޅައެވެ. އަދި ގޮވައިލިއެވެ.","",""],["","","","فقال أنا ربكم الأعلى","ފަހެ، އޭނާ ބުންޏެވެ. ތިމަންނާއީ، ތިޔަބައިމީހުންގެ އެންމެ މަތިވެރިވެގެންވާ ކަލާނގެއެވެ.","",""],["","","","فأخذه الله نكال الآخرة والأولى","ދެން އާޚިރަތާއި، ދުނިޔޭގެ އުގޫބާތެއްގެ ގޮތުން ﷲ އޭނާ ހިއްޕެވިއެވެ.","",""],["","","","إن في ذلك لعبرة لمن يخشى","ބިރުވެތިވާ މީހަކަށް ހަމަކަށަވަރުން، އެކަމުގައި އިބްރަތެއްވާކަން ކަށަވަރެވެ.","",""],["","","","أأنتم أشد خلقا أم السماء بناها","ހެއްދެވުމުގައި އުނދަގޫކަންބޮޑީ، ތިޔަބައިމީހުން ހެއްޔެވެ؟ ނުވަތަ އުޑު ހެއްޔެވެ؟ އެ އުޑު ބިނާކުރެއްވީ އެކަލާނގެއެވެ.","",""],["","","","رفع سمكها فسواها","އެކަލާނގެ އެ އުޑުގެ ބިނާ އުފުއްލެވިއެވެ. ދެން އެ އުޑު ފުރިހަމަކުރެއްވިއެވެ.","",""],["","","","وأغطش ليلها وأخرج ضحاها","އަދި އެ އުޑުގެ ރޭގަނޑު އަނދިރިކުރެއްވިއެވެ. އަދި އެ އުޑުގެ ދުވާލު ފާޅުކުރެއްވިއެވެ.","",""],["","","","والأرض بعد ذلك دحاها","އެއަށްފަހު، ބިން ފެތުރުއްވިއެވެ.","",""],["","","","أخرج منها ماءها ومرعاها","އެ ބިމުގެ ފެނާއި، ފަތްޕިލާވެލި، އެ ބިމުން ނެރުއްވިއެވެ.","",""],["","","","والجبال أرساها","އަދި ފަރުބަދަތައް (އެ ބިމުގައި) ހަރުލެއްވިއެވެ.","",""],["","","","متاعا لكم ولأنعامكم","(އެއީ) ތިޔަބައިމީހުންނަށާއި، ތިޔަބައިމީހުންގެ ނަޢަމް ސޫފިތަކަށް ދިރިއުޅުމުގެ ވަގުތީ އުފަލެއްގެ ގޮތުގައެވެ.","",""],["","","","فإذا جاءت الطامة الكبرى","ފަހެ، ބޮޑުވެގެންވާ ކަންތައްގަނޑު އަންނަހިނދެވެ. (އެބަހީ: ގިޔާމަތް ދުވަސް އަންނަހިނދެވެ.)","",""],["","","","يوم يتذكر الإنسان ما سعى","އިންސާނާ ކުޅަހާ ކަމެއް، ހަނދުމަވާ ދުވަހެވެ.","",""],["","","","وبرزت الجحيم لمن يرى","އަދި ދެކޭމީހަކަށް ނަރަކަ ފާޅުކުރައްވާނެތެވެ.","",""],["","","","فأما من طغى","ފަހެ، ފުރެދުމުގައި ހައްދުފަހަނަޅައި، އަދި ދުނިޔޭގެ ދިރިއުޅުމަށް އިސްކަންދިން މީހާ ދަންނާށެވެ!","",""],["","","","وآثر الحياة الدنيا","ފަހެ، ފުރެދުމުގައި ހައްދުފަހަނަޅައި، އަދި ދުނިޔޭގެ ދިރިއުޅުމަށް އިސްކަންދިން މީހާ ދަންނާށެވެ!","",""],["","","","فإن الجحيم هي المأوى","ފަހެ، ހަމަކަށަވަރުން، އެމީހާ އުޅޭނެ ތަނަކީ، ނަރަކަޔެވެ.","",""],["","","","وأما من خاف مقام ربه ونهى النفس عن الهوى","އަދި އެމީހާގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ހުންނަންޖެހޭ ހުރުމަށް ބިރުވެތިވެ، އެމީހެއްގެ ނަފްސު އަމިއްލަ އެދުންތަކުން ދުރުކޮށްފިމީހާ ދަންނާށެވެ!","",""],["","","","فإن الجنة هي المأوى","ފަހެ، ހަމަކަށަވަރުން، އެމީހާ އުޅޭނެ ތަނަކީ، ސުވަރުގެއެވެ.","",""],["","","","يسألونك عن الساعة أيان مرساها","ގިޔާމަތްގެ ވަގުތު އަންނާނީ ކޮންއިރަކުންކަމާމެދު އެއުރެން ކަލޭގެފާނާ ސުވާލުކުރެތެވެ.","",""],["","","","فيم أنت من ذكراها","އެކަން ބަޔާން ކޮށްދެއްވުމަކީ، ކަލޭގެފާނަށް (ކުރެއްވެން) އޮތްކަމެއްތޯއެވެ؟","",""],["","","","إلى ربك منتهاها","އެކަން ދެނެވޮޑިގަތުންވަނީ، ހަމައެކަނި، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށެވެ.","",""],["","","","إنما أنت منذر من يخشاها","ކަލޭގެފާނުވާކަން ކަށަވަރީ، އެދުވަހަށް ބިރުވެތިވާ މީހަކަށް އިންޒާރުކުރައްވާ ބޭކަލަކު ކަމުގައެވެ.","",""],["","","","كأنهم يوم يرونها لم يلبثوا إلا عشية أو ضحاها","އެއުރެން އެކަންތައް ދެކޭދުވަހު، ހަވީރެއް، ނުވަތަ ހެނދުނެއްގައި މެނުވީ، އެއުރެން ލަސްވެ ނުތިބޭކަހަލައެވެ.","",""],["","","","بسم الله الرحمن الرحيم عبس وتولى","އެކަލޭގެފާނު (އެބަހީ: މުޙައްމަދުގެފާނު) ހިތްޕުޅާނުވުމުގެ ގޮތް މޫނުފުޅުން ދައްކަވައި (އަނެއްފަރާތަށް) އެނބުރިވަޑައިގަތެވެ.","",""],["","","","أن جاءه الأعمى","ލޯފަންމީހާ އެކަލޭގެފާނުގެ އަރިހަށް އައުމުންނެވެ.","",""],["","","","وما يدريك لعله يزكى","އަދި އޭނާ ކުށްތަކުން ސާފުވެ، ތާހިރު ވެދާނެކަން، ނުވަތަ އޭނާ ހަނދުމަކޮށް، ދެން އެ ހަނދުމަކުޅައުން އޭނާޔަށް މަންފާކޮށްފާނެކަން ކަލޭގެފާނަށް އަންގައިދެނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","أو يذكر فتنفعه الذكرى","އަދި އޭނާ ކުށްތަކުން ސާފުވެ، ތާހިރު ވެދާނެކަން، ނުވަތަ އޭނާ ހަނދުމަކޮށް، ދެން އެ ހަނދުމަކުޅައުން އޭނާޔަށް މަންފާކޮށްފާނެކަން ކަލޭގެފާނަށް އަންގައިދެނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","أما من استغنى","އެމީހާ އަމިއްލަޔަށް ފުދިގެންވާކަމަށް ދެކޭމީހާ ދަންނާށެވެ!","",""],["","","","فأنت له تصدى","ފަހެ، ކަލޭގެފާނު އެމީހަކާ ކުރިމަތިލައްވަމުއެވެ.","",""],["","","","وما عليك ألا يزكى","އެމީހަކު (ކާފިރުކަމުން) ތާހިރު ނުވުމަކުން، ކަލޭގެފާނުގެ މައްޗަކަށް ކުށެއް ނެތެވެ.","",""],["","","","وأما من جاءك يسعى","އަދި ބިރުވެތިވާ ޙާލު، ކަލޭގެފާނުގެ އަރިހަށް ހިނގަމުންއައިމީހާ ދަންނާށެވެ!","",""],["","","","وهو يخشى","އަދި ބިރުވެތިވާ ޙާލު، ކަލޭގެފާނުގެ އަރިހަށް ހިނގަމުންއައިމީހާ ދަންނާށެވެ!","",""],["","","","فأنت عنه تلهى","ފަހެ، އެމީހާއާ ކަލޭގެފާނު އަޅައިނުލައްވައި މަޝްޣޫލު ވެވަޑައިގަންނަވަމުއެވެ.","",""],["","","","كلا إنها تذكرة","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ހަމަކަށަވަރުން، އެ އާޔަތް ތަކަކީ، ހަނދާންކޮށްދިނުމެކެވެ.","",""],["","","","فمن شاء ذكره","ފަހެ، ބޭނުންމީހަކު އެ ގުރްއާން ހަނދުމަކުރާހުށިކަމެވެ!","",""],["","","","في صحف مكرمة","އެ ގުރްއާން ވަނީ، މާތްކުރައްވާފައިވާ ފަތްފުށްތަކެއްގައެވެ.","",""],["","","","مرفوعة مطهرة","މަތިވެރި، ތާހިރުކުރައްވާފައިވާ ފަތްފުށްތަކެއްގައެވެ.","",""],["","","","بأيدي سفرة","ދަތުރުކުރައްވާ މަލާއިކަތުންގެ އަތްޕުޅުތަކުގައެވެ.","",""],["","","","كرام بررة","މާތްވެގެންވާ ހެޔޮލަފާ މަލާއިކަތުންނެވެ.","",""],["","","","قتل الإنسان ما أكفره","އިންސާނާއަށް ލައުނަތް ލެއްވިއެވެ. އޭނާގެ ހުރި ކާފިރުކަމުގެ ބޮޑުކަމާއެވެ!","",""],["","","","من أي شيء خلقه","އެކަލާނގެ އެ އިންސާނާ ހެއްދެވީ ކޮންއެއްޗަކުން ހެއްޔެވެ؟","",""],["","","","من نطفة خلقه فقدره","އެކަލާނގެ އެ އިންސާނާ ހެއްދެވީ މަނިތިއްކަކުންނެވެ. ދެން އެކަލާނގެ އެ އިންސާނާ (ގެ ހުރިހާ ކަމެއް) މިންވަރު ކުރެއްވިއެވެ.","",""],["","","","ثم السبيل يسره","ދެން އެކަލާނގެ އޭނާޔަށް މަގު ފަސޭހަކޮށްދެއްވިއެވެ.","",""],["","","","ثم أماته فأقبره","ދެން އެކަލާނގެ އޭނާ މަރުގެންނެވިއެވެ. އަދި އޭނާ ކަށްވަޅުގައި ލެއްވިއެވެ.","",""],["","","","ثم إذا شاء أنشره","ދެން އެކަލާނގެ އިރާދަކުރައްވާ ހިނދު، އެ އިންސާނާ އަލުން ދިރުމަކަށް ފޮނުއްވާނެތެވެ.","",""],["","","","كلا لما يقض ما أمره","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. އެ އިންސާނާ އަދިވެސް، އެކަލާނގެ އޭނާޔަށް އަމުރުކުރެއްވި ކަންތަކެއް ނުކުރެތެވެ.","",""],["","","","فلينظر الإنسان إلى طعامه","ފަހެ، އެ އިންސާނާ އޭނާގެ ކާތަކެއްޗަށް ބަލައިފާހުށިކަމެވެ!","",""],["","","","أنا صببنا الماء صبا","ބޯކޮށް އޮހިގެން އަންނަގޮތުގައި، ތިމަންރަސްކަލާނގެ ފެން އޮއްސެވީމެވެ.","",""],["","","","ثم شققنا الأرض شقا","ދެން ތިމަންރަސްކަލާނގެ (ގަސްހެދުމަށް ފަސޭހަވާނެގޮތުން) ބިންގަނޑު ފެޅުއްވީމެވެ.","",""],["","","","فأنبتنا فيها حبا","ދެން ތިމަންރަސްކަލާނގެ އެ ބިމުގައި ގޮވާން (ގަސްތައް) ފެޅުއްވީމެވެ.","",""],["","","","وعنبا وقضبا","އަދި މޭބިސްކަދުރާއި ފަތްޕިލާވެއްޔެވެ.","",""],["","","","وزيتونا ونخلا","އަދި ޒައިތޫނި ގަހާއި ކަދުރު ރުކެވެ.","",""],["","","","وحدائق غلبا","އަދި ގަސްތައްގިނަ ބަގީޗާތަކެވެ.","",""],["","","","وفاكهة وأبا","މޭވާގެ ބާވަތްތަކާއި ހުއިތަކެވެ.","",""],["","","","متاعا لكم ولأنعامكم","(އެއީ) ތިޔަބައިމީހުންނަށާއި، ތިޔަބައިމީހުންގެ ނަޢަމް ސޫފިތަކަށް ދިރިއުޅުމުގެ ވަގުތީ އުފަލެއްގެ ގޮތުގައެވެ.","",""],["","","","فإذا جاءت الصاخة","ފަހެ، ގަދަފަދަ އަޑު އަތުވެއްޖެހިނދެވެ.","",""],["","","","يوم يفر المرء من أخيه","(އެއީ) މީހާ އޭނާގެ އަޚާގެ ކިބައިންނާއި، އޭނާގެ މަންމައާއި، ބައްޕަގެ ކިބައިންނާއި، އޭނާގެ އަނބިމީހާއާއި، ދަރިންގެ ކިބައިން ފިލަންދާ ދުވަހެވެ.","",""],["","","","وأمه وأبيه","(އެއީ) މީހާ އޭނާގެ އަޚާގެ ކިބައިންނާއި، އޭނާގެ މަންމައާއި، ބައްޕަގެ ކިބައިންނާއި، އޭނާގެ އަނބިމީހާއާއި، ދަރިންގެ ކިބައިން ފިލަންދާ ދުވަހެވެ.","",""],["","","","وصاحبته وبنيه","(އެއީ) މީހާ އޭނާގެ އަޚާގެ ކިބައިންނާއި، އޭނާގެ މަންމައާއި، ބައްޕަގެ ކިބައިންނާއި، އޭނާގެ އަނބިމީހާއާއި، ދަރިންގެ ކިބައިން ފިލަންދާ ދުވަހެވެ.","",""],["","","","لكل امرئ منهم يومئذ شأن يغنيه","އެއުރެންކުރެ ކޮންމެ މީހަކަށް، އެމީހަކު އަވަދިނެތި ކުރާނެކަމެއް އެދުވަހުން ވެއެވެ.","",""],["","","","وجوه يومئذ مسفرة","އެދުވަހުން އަލިވެ، ހިނިއައިސް، އުފާވެފައިވާ މޫނުތަކެއްވާނެއެވެ.","",""],["","","","ضاحكة مستبشرة","އެދުވަހުން އަލިވެ، ހިނިއައިސް، އުފާވެފައިވާ މޫނުތަކެއްވާނެއެވެ.","",""],["","","","ووجوه يومئذ عليها غبرة","އަދި އެދުވަހުން އެ މޫނުތަކެއްގެ މައްޗަށް ހިރަފުސް އަރާފައިވާ މޫނުތަކެއްވެސް ވާނެއެވެ.","",""],["","","","ترهقها قترة","އެ މޫނުތަކަށް ކަޅުއަނދިރިކަމެއް ވެރިވާނެތެވެ.","",""],["","","","أولئك هم الكفرة الفجرة","އެއުރެންނީ ހަމަ، ނުލަފާވެގެންވާ ކާފިރުންނެވެ.","",""],["","","","بسم الله الرحمن الرحيم إذا الشمس كورت","އިރުގެ އަލިކަން ފިލައި، ހިނގައިދާ ހިނދެވެ.","",""],["","","","وإذا النجوم انكدرت","އަދި ތަރިތަކުން އަލިކަން ފިލައި، ބުރަބުރައިގެންދާ ހިނދެވެ.","",""],["","","","وإذا الجبال سيرت","އަދި ފަރުބަދަތައް ލުހި، ފުނޑުފުނޑުވާ ހިނދެވެ.","",""],["","","","وإذا العشار عطلت","އަދި މާބަނޑު ޖަމަލުތައް އަޅާނުލައި ދޫކޮށްލާ ހިނދެވެ.","",""],["","","","وإذا الوحوش حشرت","އަދި ވަލު ޖަނަވާރުތައް (އެއްތަނަކަށް) އެއްކުރައްވާ ހިނދެވެ.","",""],["","","","وإذا البحار سجرت","އަދި ކަނޑުތައް ރޯވެ، އަނދައިގަންނަ ހިނދެވެ.","",""],["","","","وإذا النفوس زوجت","އަދި ފުރާނަތައް، އޭގެ ހަށިތަކާ ގުޅިދާހިނދެވެ.","",""],["","","","وإذا الموءودة سئلت","އަދި ދިރިއޮއްވައި ވަޅުލި އަންހެން ދަރިޔާއާ ސުވާލުކުރައްވާ ހިނދެވެ.","",""],["","","","بأي ذنب قتلت","އޭނާ މަރައިލީ ކޮން ކުށެއްގެ ސަބަބުން ހެއްޔެވެ؟","",""],["","","","وإذا الصحف نشرت","އަދި ފަތްފުށްތައް ނިއުޅައިލައްވާ ހިނދެވެ.","",""],["","","","وإذا السماء كشطت","އަދި އުޑު ގެންދަވާ ހިނދެވެ.","",""],["","","","وإذا الجحيم سعرت","އަދި ނަރަކަ ރޯކޮށްލައްވާ ހިނދެވެ.","",""],["","","","وإذا الجنة أزلفت","އަދި ސުވަރުގެ ގާތްކުރައްވާ ހިނދެވެ.","",""],["","","","علمت نفس ما أحضرت","ކޮންމެ ނަފްސަކަށްމެ، އެ ނަފްސެއް ޙާޒިރުުކުޅަކަމެއް (އެހިނދު) އެނގޭނެތެވެ.","",""],["","","","فلا أقسم بالخنس","ފަހެ، ރޭގަނޑަށް ފާޅުކަންބޮޑު، ދުވާލު ވަންހަނާވާ، ހިނގަހިނގާ ހުންނަ ތަރިތައް ގަންދެއްވަމެވެ.","",""],["","","","الجوار الكنس","ފަހެ، ރޭގަނޑަށް ފާޅުކަންބޮޑު، ދުވާލު ވަންހަނާވާ، ހިނގަހިނގާ ހުންނަ ތަރިތައް ގަންދެއްވަމެވެ.","",""],["","","","والليل إذا عسعس","އަދި ރޭގަނޑު އަނދިރިކަމާއިގެން ފަސްދީދާހިނދު، އެ ރޭގަނޑު ގަންދެއްވަމެވެ.","",""],["","","","والصبح إذا تنفس","އަދި ފަތިހުގެ އަލިކަން ފާޅުވާހިނދު، އެ ފަތިސް ގަންދެއްވަމެވެ.","",""],["","","","إنه لقول رسول كريم","ހަމަކަށަވަރުން، އެއީ މާތްވެގެންވާ ރަސޫލަކު (އެބަހީ: ޖިބްރީލުގެފާނު) ގެންނެވި ބަސްފުޅުކަން ކަށަވަރެވެ.","",""],["","","","ذي قوة عند ذي العرش مكين","ޢަރްޝުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި ބާރެއްގެ ވެރި ދަރަޖަވެރިޔެކެވެ.","",""],["","","","مطاع ثم أمين","އެތާނގައި (އެބަހީ: އުޑުތަކުގައި) ކިޔަމަންވެވޭ އަމާނާތްތެރިޔެކެވެ.","",""],["","","","وما صاحبكم بمجنون","އަދި ތިޔަބައިމީހުންގެ އެކުވެރިޔާއީ (އެބަހީ: މުޙައްމަދުގެފާނީ) މޮޔައަކު ކަމުގައި ނުވެއެވެ.","",""],["","","","ولقد رآه بالأفق المبين","އަދި ހަމަކަށަވަރުން، އެކަލޭގެފާނު (އެބަހީ: މުޙައްމަދުގެފާނު) ފާޅުވެގެންވާ އުދަރެހުން އެކަލޭގެފާނު (އެބަހީ: ޖިބްރީލުގެފާނު) ދެކެވަޑައިގަތެވެ.","",""],["","","","وما هو على الغيب بضنين","އަދި ޣައިބުގެ ކަންތައް ފޮރުވައި، ހިފަހައްޓަވާ ބޭކަލަކު ކަމުގައި އެކަލޭގެފާނު (އެބަހީ: މުޙައްމަދުގެފާނު) ނުވެއެވެ.","",""],["","","","وما هو بقول شيطان رجيم","އަދި ރަހުމަތުން ބޭރުކުރައްވާފައިވާ ޝައިތާނެއްގެ ބަސްކަމުގައިވެސް އެ ގުރްއާން ނުވެއެވެ.","",""],["","","","فأين تذهبون","ފަހެ، ތިޔަބައިމީހުން ތިޔަދަނީ ކޮންތާކަށް ހެއްޔެވެ؟","",""],["","","","إن هو إلا ذكر للعالمين","އާލަމްތަކަށް ހަނދާންކޮށްދިނުމެއް ކަމުގައި މެނުވީ އެ ގުރްއާން ނުވެއެވެ.","",""],["","","","لمن شاء منكم أن يستقيم","ތިޔަބައިމީހުންކުރެ ސީދާވެގަތުމަށް އެދޭ މީހަކަށްޓަކައެވެ.","",""],["","","","وما تشاءون إلا أن يشاء الله رب العالمين","އާލަމްތަކުގެ ވެރި ﷲ އިރާދަކުރެއްވުމުން މެނުވީ، ތިޔަބައިމީހުންނަކަށް (އެއްވެސް ކަމެއް) ނޭދެވޭނެތެވެ.","",""],["","","","بسم الله الرحمن الرحيم إذا السماء انفطرت","ސއުޑު ފަޅަފަޅައިގެންދާ ހިނދެވެ.","",""],["","","","وإذا الكواكب انتثرت","އަދި ތަރިތައް ވެރި، ބުރައިގެންދާ ހިނދެވެ.","",""],["","","","وإذا البحار فجرت","އަދި ކަނޑުތައް ހުޅުވި، އެއްކަނޑު އަނެއްކަނޑާ ގުޅޭހިނދެވެ.","",""],["","","","وإذا القبور بعثرت","އަދި ކަށްވަޅުތައް އެފުށްމިފުށަށްޖެހި، ކަށްތައް ނެރެލައްވާހިނދެވެ.","",""],["","","","علمت نفس ما قدمت وأخرت","(އެހިނދު) ކޮންމެ ނަފްސަކަށް، އެ ނަފްސެއް އިސްކުޅަހާ ކަމަކާއި، ފަސްކުޅަހާ ކަމެއް އެނގޭނެތެވެ.","",""],["","","","يا أيها الإنسان ما غرك بربك الكريم","އޭ އިންސާނާއެވެ! ތިބާގެ ވެރި، ދީލަތިވަންތަ ރަސްކަލާނގެއާމެދު ތިބާ ހެއްލުންތެރިކުޅައީ ކޮންއެއްޗެއް ހެއްޔެވެ؟","",""],["","","","الذي خلقك فسواك فعدلك","އެކަލާނގެއީ، ތިބާ ހައްދަވައި، އަދި ތިބާގެ ގުނަންތައް ފުރިހަމަކުރައްވައި، އިސްކޮޅާ ރޫފަ ގުޅޭގޮތަށް ތިބާ ލެއްވި ރަސްކަލާނގެއެވެ.","",""],["","","","في أي صورة ما شاء ركبك","އެކަލާނގެ އިރާދަކުރެއްވި ކޮންމެ ސިފަޔަކަށް، އެކަލާނގެ، ތިބާ، ތަރުކީބުކުރެއްވިއެވެ.","",""],["","","","كلا بل تكذبون بالدين","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. އަދި ކިއެއްތަ! (ގިޔާމަތް ދުވަހުން) ޖަޒާ ދެއްވާނޭކަން ތިޔަބައިމީހުން ދޮގުކުރަމުއެވެ.","",""],["","","","وإن عليكم لحافظين","އަދި ހަމަކަށަވަރުން، ތިޔަބައިމީހުންގެ މައްޗަށް ރައްކާތެރިވެ ބަލަހައްޓަވާ މަލާއިކަތް ންވެއެވެ.","",""],["","","","كراما كاتبين","(އެއީ) މާތްވެގެންވާ، ލިޔުއްވާ މަލާއިކަތުންނެވެ.","",""],["","","","يعلمون ما تفعلون","ތިޔަބައިމީހުން ކުރާ ކަންތައް އެ މަލާއިކަތުން ދެނެވަޑައިގެންވެތެވެ.","",""],["","","","إن الأبرار لفي نعيم","ހަމަކަށަވަރުން، ހެޔޮލަފާ މީހުންވަނީ، ނިއުމަތްގެ ސުވަރުގޭގައިކަން ކަށަވަރެވެ.","",""],["","","","وإن الفجار لفي جحيم","އަދި ހަމަކަށަވަރުން، ކާފިރު ންވަނީ، ނަރަކައިގައިކަން ކަށަވަރެވެ.","",""],["","","","يصلونها يوم الدين","ގިޔާމަތް ދުވަހު އެއުރެން އެ ނަރަކަޔަށް ވަންނާނެތެވެ.","",""],["","","","وما هم عنها بغائبين","އެއުރެން އެ ނަރަކައިން ނުކުންނާނޭ ބަޔަކު ކަމުގައެއް ނުވެއެވެ.","",""],["","","","وما أدراك ما يوم الدين","ގިޔާމަތް ދުވަހަކީ، ކޮންދުވަހެއްކަން ކަލޭގެފާނަށް އަންގައިދިނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","ثم ما أدراك ما يوم الدين","ދެންވެސް ގިޔާމަތް ދުވަހަކީ، ކޮންދުވަހެއްކަން ކަލޭގެފާނަށް އަންގައިދިނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","يوم لا تملك نفس لنفس شيئا والأمر يومئذ لله","(އެއީ) އެއްވެސް ނަފްސެއް، އަނެއް ނަފްސަކަށް އެއްވެސްކަމެއް ކޮށްދިނުން މިލްކުވެގެންނުވާ ދުވަހެވެ. އަދި އެދުވަހުން، އަމުރުވެރިކަން މިލްކުވެގެންވަނީ (ހަމައެކަނި) ﷲއަށެވެ.","",""],["","","","بسم الله الرحمن الرحيم ويل للمطففين","މިނެކިރުމުގައި އުނިކުރާ މީހުންނަށް، ގެއްލުމާއި ހަލާކު ހުށްޓެވެ.","",""],["","","","الذين إذا اكتالوا على الناس يستوفون","އެއުރެންނީ، އެހެންމީހުންގެ ކިބައިން މިނާނަމަ، ހަމަކުރަން އެދޭމީހުންނެވެ.","",""],["","","","وإذا كالوهم أو وزنوهم يخسرون","އަދި އެހެންމީހުންނަށް މިނެދޭނަމަ، ނުވަތަ އެހެންމީހުންނަށް ކިރައިދޭނަމަ، ގެއްލުންކުރާ މީހުންނެވެ.","",""],["","","","ألا يظن أولئك أنهم مبعوثون","ބޮޑުވެގެންވާ ދުވަހަކަށް އެއުރެން ފޮނުއްވާނޭ ކަމުގައި އެއުރެން ޔަގީން ނުކުރަނީ ހެއްޔެވެ؟","",""],["","","","ليوم عظيم","ބޮޑުވެގެންވާ ދުވަހަކަށް އެއުރެން ފޮނުއްވާނޭ ކަމުގައި އެއުރެން ޔަގީން ނުކުރަނީ ހެއްޔެވެ؟","",""],["","","","يوم يقوم الناس لرب العالمين","(އެއީ) އާލަމްތަކުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި މީސްތަކުން ގާއިމުވެ ތިބޭނޭ ދުވަހެވެ.","",""],["","","","كلا إن كتاب الفجار لفي سجين","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ހަމަކަށަވަރުން، ނުލަފާ ކާފިރުންގެ ޢަމަލުތަކުގެ ފަތްވަނީ ސިއްޖީން ގައިކަން ކަށަވަރެވެ.","",""],["","","","وما أدراك ما سجين","ސިއްޖީނަކީ ކޮންއެއްޗެއްކަން ކަލޭގެފާނަށް އަންގައިދިނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","كتاب مرقوم","(އެއީ) ލިޔުއްވައި، ފާހަގަކުރައްވާފައިވާ ފޮތެކެވެ.","",""],["","","","ويل يومئذ للمكذبين","ދޮގުކުރާ މީހުންނަށް އެދުވަހުން ގެއްލުމާއި ހަލާކު ހުށްޓެވެ.","",""],["","","","الذين يكذبون بيوم الدين","އެއުރެންނީ، ގިޔާމަތް ދުވަސް ދޮގުކުރާ މީހުންނެވެ.","",""],["","","","وما يكذب به إلا كل معتد أثيم","ހައްދުފަހަނަޅައިފައިވާ، ފާފަކުރުންގިނަ ކޮންމެ މީހަކު މެނުވީ، އެދުވަސް ދޮގެއް ނުކުރާނެތެވެ.","",""],["","","","إذا تتلى عليه آياتنا قال أساطير الأولين","ތިމަންރަސްކަލާނގެ އާޔަތްތައް އޭނާޔަށް ކިޔައިދެއްވާހިނދު، އޭނާ ބުނެތެވެ. (ތިޔައީ) އެވޭލާ މީހުން ދައްކައިއުޅުނު ފުލޯކު ވާހަކަތަކެވެ.","",""],["","","","كلا بل ران على قلوبهم ما كانوا يكسبون","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. އަދި ކީއްހެއްޔެވެ؟ އެއުރެން ހޯދައިއުޅުނު ޢަމަލުތަކުގެ ސަބަބުން އެއުރެންގެ ހިތްތަކުގައި ދަބަރުޖަހާފައިވެއެވެ.","",""],["","","","كلا إنهم عن ربهم يومئذ لمحجوبون","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ހަމަކަށަވަރުން، އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުން އެދުވަހު، އެއުރެން ފަރުދާ ކުރެވިގެންވާނޭކަން ކަށަވަރެވެ.","",""],["","","","ثم إنهم لصالو الجحيم","ދެން ހަމަކަށަވަރުން، އެއުރެން ނަރަކަޔަށް ވަންނާނެކަން ކަށަވަރެވެ.","",""],["","","","ثم يقال هذا الذي كنتم به تكذبون","ދެން (އެއުރެންނަށް) އަންގަވާނެތެވެ. ތިޔަބައިމީހުން ދޮގުކޮށް އުޅުނު ކަންތަކަކީ މިއީއެވެ.","",""],["","","","كلا إن كتاب الأبرار لفي عليين","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ހަމަކަށަވަރުން، ހެޔޮލަފާ މީހުންގެ ޢަމަލުތަކުގެ ފަތްވަނީ ޢިއްލިއްޔޫންގައި ކަންކަށަވަރެވެ.","",""],["","","","وما أدراك ما عليون","ޢިއްލިއްޔޫނަކީ، ކޮންއެއްޗެއްކަން ކަލޭގެފާނަށް އަންގައިދިނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","كتاب مرقوم","(އެއީ) ލިޔުއްވައި ފާހަގަކުރައްވާފައިވާ ފޮތެކެވެ.","",""],["","","","يشهده المقربون","ކުއްތަންކުރައްވާފައިވާ މަލާއިކަތުން އެ ފޮތް ދެކެވަޑައިގަންނަވާނެތެވެ.","",""],["","","","إن الأبرار لفي نعيم","ހަމަކަށަވަރުން، ހެޔޮލަފާ މީހުންވަނީ، ނިއުމަތްގެ ސުވަރުގޭގައިކަން ކަށަވަރެވެ.","",""],["","","","على الأرائك ينظرون","ދާންތަކުގެ މަތީގައި (ނިއުމަތްތަކަށް) ބަލަބަލައެވެ.","",""],["","","","تعرف في وجوههم نضرة النعيم","އެއުރެންގެ މޫނުތަކުގެމަތިން، ނިއުމަތްގެ އުފާވެރިކަން ތިބާޔަށް އެނގޭނެތެވެ.","",""],["","","","يسقون من رحيق مختوم","ސިއްކަގައްސަވައި ބަންދުކުރައްވާފައިވާ (މަސްތުވުމެއްނެތް) ސާފު ރާގެ ބުއިމަކުން، އެއުރެންނަށް ބޯންދެއްވާނެތެވެ.","",""],["","","","ختامه مسك وفي ذلك فليتنافس المتنافسون","އެބުއިން ނިމޭހުށީ، ކަސްތޫރި ވަހުންނެވެ. ވާދަކޮށް ކުރިއަރައިދާ މީހުން އެއާމެދުގައި ވާދަކޮށް ކުރިއަރައިދާ ހުށިކަމެވެ!","",""],["","","","ومزاجه من تسنيم","އެއާ އެއްކުރައްވާފައިވަނީ ތަސްނީމެވެ.","",""],["","","","عينا يشرب بها المقربون","(އެއީ) ކުއްތަންވެގެންވާ އަޅުން އެއިން ބޯނޭ އާރެކެވެ.","",""],["","","","إن الذين أجرموا كانوا من الذين آمنوا يضحكون","ހަމަކަށަވަރުން، ކުށްވެރި، ފާފަވެރިން (ދުނިޔޭގައި) އީމާންވި މީހުންނާ ދިމާޔަށް (މަލާމާތުގެގޮތުން) ހީނއުޅޭ ކަމުގައިވޫއެވެ.","",""],["","","","وإذا مروا بهم يتغامزون","އަދި އެއުރެން އެ މުއުމިނުންގެ ކައިރިންދާހިނދު، ލޮލުގެ އިޝާރަތުން ފުރައްސާރަ ކުރެތެވެ.","",""],["","","","وإذا انقلبوا إلى أهلهم انقلبوا فكهين","އަދި އެއުރެންގެ އަހުލުވެރިންގެގާތަށް އެނބުރިދާހިނދު، ހީނސަމާސާ ކުރަމުންދެއެވެ.","",""],["","","","وإذا رأوهم قالوا إن هؤلاء لضالون","އަދި އެއުރެން މުއުމިނުން ދެކޭހިނދު ބުނެތެވެ. ހަމަކަށަވަރުން، މިބައިމީހުންނީ، މަގު ގެއްލިފައިވާ ބަޔެއްކަން ކަށަވަރެވެ.","",""],["","","","وما أرسلوا عليهم حافظين","އަދި މުއުމިނުންގެ މައްޗަށް ރައްކާތެރިވެ، ބަލަހައްޓާ ބަޔަކު ކަމުގައި އެ ކާފިރުން ފޮނުއްވާފައެއް ނުވެއެވެ.","",""],["","","","فاليوم الذين آمنوا من الكفار يضحكون","ފަހެ، އީމާންވި މީހުން މިއަދު ކާފިރުންނާ ދިމާޔަށް ހޭނެތެވެ.","",""],["","","","على الأرائك ينظرون","ދާންތަކުގެ މަތީގައި (ނިއުމަތްތަކަށް) ބަލަބަލައެވެ.","",""],["","","","هل ثوب الكفار ما كانوا يفعلون","ކާފިރުންނަށް އެއުރެން ކޮށްއުޅުނު ކަންތަކަށް ޖަޒާ ލިބިއްޖެ ހެއްޔެވެ؟","",""],["","","","بسم الله الرحمن الرحيم إذا السماء انشقت","އުޑުފަޅަފަޅައިގެންދާ ހިނދެވެ.","",""],["","","","وأذنت لربها وحقت","އަދި އެ އުޑުގެ ވެރިރަސްކަލާނގެ އަމުރު ފުޅަށް އެ އުޑު ކިޔަމަންވާހިނދެވެ. އެ އުޑަށް އެކަން ހައްގު ވެގެންވެއެވެ.","",""],["","","","وإذا الأرض مدت","އަދި ބިންގަނޑު ދެމި، ފެތުރިގެންދާ ހިނދެވެ.","",""],["","","","وألقت ما فيها وتخلت","އަދި އެ ބިމުގެ ތެރޭގައިވާ ތަކެތި އުކާލައި، އެ ބިން ހުސްވެގެންދާ ހިނދެވެ.","",""],["","","","وأذنت لربها وحقت","އަދި އެ ބިމުގެ ވެރިރަސްކަލާނގެ އަމުރު ފުޅަށް އެ ބިން ކިޔަމަންވާ ހިނދެވެ. އެ ބިމަށް އެކަން ހައްގު ވެގެންވެއެވެ.","",""],["","","","يا أيها الإنسان إنك كادح إلى ربك كدحا فملاقيه","އޭ އިންސާނާއެވެ! ހަމަކަށަވަރުން، ތިބާއީ، ތިބާގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް ދިޔުމަށް ވަރަށްބޮޑަށް ގަދައަޅައި މަސައްކަތްކުރާ މީހެކެވެ. ފަހެ، ތިބާ (އެ މަސައްކަތާއިގެން) އެކަލާނގެއާ ބައްދަލުވާނެތެވެ.","",""],["","","","فأما من أوتي كتابه بيمينه","ފަހެ، އެމީހެއްގެ ފަތް، އެމީހެއްގެ ކަނާތަށް ލިބުނު މީހާ ދަންނާށެވެ!","",""],["","","","فسوف يحاسب حسابا يسيرا","ފަހެ، ލުއިފަސޭހަވެގެންވާ ހިސާބު ބެއްލެވުމަކުން، ނިކަންހުރެ އެމީހަކާމެދު ހިސާބު ބައްލަވާނެތެވެ.","",""],["","","","وينقلب إلى أهله مسرورا","އަދި އުފަލުންހުރެ، އޭނާގެ އަހުލުވެރިންގެގާތަށް (ސުވަރުގެޔަށް) އެނބުރިދާނެތެވެ.","",""],["","","","وأما من أوتي كتابه وراء ظهره","އަދި އެމީހެއްގެ ފަތް، އެމީހެއްގެ ފުރަގަހުން (ވާތަށް) ލިބުނުމީހާ ދަންނާށެވެ.","",""],["","","","فسوف يدعو ثبورا","ފަހެ، ނިކަންހުރެ އެމީހަކު ގޮވާނެތެވެ. އޭ ހުރި ހަލާކެއްގެ ބޮޑުކަމާއެވެ!","",""],["","","","ويصلى سعيرا","އަދި އަނދައަނދާ ހުންނަ ނަރަކަޔަކަށް އޭނާ ވަންނާނެތެވެ.","",""],["","","","إنه كان في أهله مسرورا","ހަމަކަށަވަރުން، އޭނާގެ އަހުލުވެރިންގެ ގާތުގައި އުފާވެރިވެގެންވާ މީހަކު ކަމުގައި (ދުނިޔޭގައި) އޭނާވިއެވެ.","",""],["","","","إنه ظن أن لن يحور","ހަމަކަށަވަރުން (އޭނާގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް) އެނބުރި ނުދާނޭކަމަށް އޭނާ ހީކުޅައެވެ.","",""],["","","","بلى إن ربه كان به بصيرا","އެހެންނަކުންނޫނެވެ. ހަމަކަށަވަރުން، އޭނާގެ ވެރިރަސްކަލާނގެ އޭނާ ދެކެވޮޑިގެންވާ ކަމުގައިވެއެވެ.","",""],["","","","فلا أقسم بالشفق","ފަހެ، ތިމަންރަސްކަލާނގެ ރަތްވިލާ ގަންދެއްވަމެވެ.","",""],["","","","والليل وما وسق","އަދި ރޭގަނޑާއި، އެ ރޭގަނޑު އެއްކުޅަހާ ތަކެތި ގަންދެއްވަމެވެ.","",""],["","","","والقمر إذا اتسق","އަދި ހަނދުގެ އަލިކަން ފުރިހަމަވާހިނދު، އެ ހަނދު ގަންދެއްވަމެވެ.","",""],["","","","لتركبن طبقا عن طبق","ހަމަކަށަވަރުން، ތިޔަބައިމީހުން އެއް ޙާލަތަކަށްފަހު، އަނެއް ޙާލަތަކަށް ބަދަލުވަމުން ދާނޭކަން ކަށަވަރެވެ.","",""],["","","","فما لهم لا يؤمنون","އެއުރެން އީމާން ނުވަނީ ފަހެ، އެއުރެންނަށް ކީއްވެގެން ހެއްޔެވެ؟","",""],["","","","وإذا قرئ عليهم القرآن لا يسجدون","އަދި އެއުރެންނަށް ގުރްއާން ކިޔަވައިދެވޭހިނދު، އެއުރެން ސަޖިދެއް ނުކުރެތެވެ.","",""],["","","","بل الذين كفروا يكذبون","އަދި ކިއެއްތަ! ކާފިރުވި މީހުން (އެ ގުރްއާން) ދޮގުކުރޫއެވެ.","",""],["","","","والله أعلم بما يوعون","އަދި އެއުރެންގެ ހިތްތަކުގައި ފޮރުވާފައިވާ ކަންތައް، ﷲ ދެނެވޮޑިގަތުން ބޮޑެވެ.","",""],["","","","فبشرهم بعذاب أليم","ފަހެ، ވޭންދެނިވި އަޒާބު ހުރިކަމުގެ ވާހަކައިން ކަލޭގެފާނު އެއުރެންނަށް ޚަބަރު ދެއްވާށެވެ!","",""],["","","","إلا الذين آمنوا وعملوا الصالحات لهم أجر غير ممنون","އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަމީހުން މެނުވީއެވެ. އެއުރެންނަށް ކެނޑިގެންނުދާނޭ ދަރުމަހުށްޓެވެ.","",""],["","","","بسم الله الرحمن الرحيم والسماء ذات البروج","ބުރުޖު ތަކުގެވެރި އުޑު ގަންދެއްވަމެވެ.","",""],["","","","واليوم الموعود","އަދި ވައުދުކުރައްވާފައިވާ ދުވަސް ގަންދެއްވަމެވެ.","",""],["","","","وشاهد ومشهود","އަދި ހެކިދޭ ފަރާތާއި، ހެކިދެވޭ ފަރާތް ގަންދެއްވަމެވެ.","",""],["","","","قتل أصحاب الأخدود","ވަޅުގަނޑުގެ އެކުވެރިންނަށް ލައުނަތް ލެއްވިއެވެ.","",""],["","","","النار ذات الوقود","(އެ ވަޅުގަނޑަކީ) ދަރުއަޅައި ރޯކޮށްފައިވާ އަލިފާންގަނޑެވެ.","",""],["","","","إذ هم عليها قعود","އެއުރެން އޭގެކައިރީގައި އިށީނދެ ތިބިހިނދެވެ.","",""],["","","","وهم على ما يفعلون بالمؤمنين شهود","މުއުމިނުންނަށް އެއުރެން ކަންތައްކުރާގޮތް، އެއުރެން ދެކޭންތިބި ޙާލު ގައެވެ.","",""],["","","","وما نقموا منهم إلا أن يؤمنوا بالله العزيز الحميد","އަދި ޢަޒީޒުވަންތަ، ގިނަގިނައިން ހަމްދު ލިބިވޮޑިގެންވާ ﷲއަށް އެއުރެން އީމާން ވާކަމަށްޓަކައި މެނުވީ، އެ ކާފިރުން އެއުރެންނާމެދު ނުރުހުންތެރިއެއް ނުވެތެވެ.","",""],["","","","الذي له ملك السماوات والأرض والله على كل شيء شهيد","އެކަލާނގެއީ، އުޑުތަކާއި، ބިމުގެ ވެރިކަން އެކަލާނގެއަށް މިލްކުވެގެންވާ ރަސްކަލާނގެއެވެ. ﷲއީ، ކޮންމެ ކަމެއްގެ މައްޗަށް ހެކިވެވޮޑިގެންވާ ރަސްކަލާނގެއެވެ.","",""],["","","","إن الذين فتنوا المؤمنين والمؤمنات ثم لم يتوبوا فلهم عذاب جهنم ولهم عذاب الحريق","ހަމަކަށަވަރުން، މުއުމިނު ފިރިހެނުންނާއި، މުއުމިނު އަންހެނުން، ދީނުން އެއްކިބާކުރުމަށް އަނިޔާދީ އުނދަގޫކޮށް، ދެން ތައުބާ ނުވި މީހުން (ދަންނާށެވެ!) ފަހެ، އެއުރެންނަށް ނަރަކައިގެ އަޒާބު ހުށްޓެވެ. އަދި އެއުރެންނަށް އަނދައަނދާ ހުންނަ އަލިފާނުގެ އަޒާބު ހުށްޓެވެ.","",""],["","","","إن الذين آمنوا وعملوا الصالحات لهم جنات تجري من تحتها الأنهار ذلك الفوز الكبير","ހަމަކަށަވަރުން، އީމާންވެ ސާލިހު ޢަމަލުތައްކުޅަމީހުންނަށް، އެތާނގެ ދަށުން ކޯރުތައް ހިނގަހިނގާ ހުންނަ ސުވަރުގެތައް ހުށްޓެވެ. ބޮޑުވެގެންވާ ނަސީބު ލިބުމަކީ އެއީއެވެ.","",""],["","","","إن بطش ربك لشديد","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހިއްޕަވާ ހިއްޕެވުމަކީ، ގަދަފަދަވެގެންވާ ހިއްޕެވުމެއްކަން ކަށަވަރެވެ.","",""],["","","","إنه هو يبدئ ويعيد","ހަމަކަށަވަރުން، ފުރަތަމަ އުފައްދަވަނީވެސް، އަދި އަލުން (ދިރުއްވައި) އިއާދަކުރައްވާނީވެސް ހަމަ އެކަލާނގެއެވެ.","",""],["","","","وهو الغفور الودود","އަދި އެކަލާނގެއީ، ގިނަގިނައިން ފާފަފުއްސަވާ، ނުހަނު އޯގާވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","ذو العرش المجيد","ޢަރްޝުގެ ވެރި، މާތްވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","فعال لما يريد","އިރާދަކުރައްވާ ކޮންމެ ކަމެއް ކުރައްވާ ރަސްކަލާނގެއެވެ.","",""],["","","","هل أتاك حديث الجنود","ފިރްޢައުނާއި، ޘަމޫދު ބާގައިގެ ލަޝްކަރުގެ ވާހަކަ، ކަލޭގެފާނާ ހަމަޔަށް އައިސްފައިވޭތޯއެވެ؟","",""],["","","","فرعون وثمود","ފިރްޢައުނާއި، ޘަމޫދު ބާގައިގެ ލަޝްކަރުގެ ވާހަކަ، ކަލޭގެފާނާ ހަމަޔަށް އައިސްފައިވޭތޯއެވެ؟","",""],["","","","بل الذين كفروا في تكذيب","އަދި ކިއެއްތަ! ކާފިރު ވިމީހުން ވަނީ، ދޮގުކުރުމެއްގައެވެ.","",""],["","","","والله من ورائهم محيط","ﷲއެއުރެންގެ ހުރިހާކަމެއް ފުރިހަމަޔަށް ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","بل هو قرآن مجيد","އަދި ކިއެއްތަ! އެއީ ރައްކާތެރި ކުރައްވާފައިވާ ފިލަޔެއްގައިވާ (އެބަހީ: އައްލައުޙުލް މަޙްފޫޡު ގައިވާ) މާތް ގުރްއާނެވެ.","",""],["","","","في لوح محفوظ","އަދި ކިއެއްތަ! އެއީ ރައްކާތެރި ކުރައްވާފައިވާ ފިލަޔެއްގައިވާ (އެބަހީ: އައްލައުޙުލް މަޙްފޫޡު ގައިވާ) މާތް ގުރްއާނެވެ.","",""],["","","","بسم الله الرحمن الرحيم والسماء والطارق","އުޑާއި، އަދި ރޭގަނޑަށް ފާޅުކަންބޮޑު ތަރި ގަންދެއްވަމެވެ.","",""],["","","","وما أدراك ما الطارق","އަދި ރޭގަނޑަށް ފާޅުކަންބޮޑު ތަރިޔަކީ، ކޮންއެއްޗެއްކަން ކަލޭގެފާނަށް އަންގައިދިނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","النجم الثاقب","އެއީ އަނދިރިކަން ތޮރުފައިލާ، އަލިކަންގަދަ ތަރިއެވެ.","",""],["","","","إن كل نفس لما عليها حافظ","އެއްވެސް ނަފްސެއް، އެ ނަފްސެއްގެ މައްޗަށް ރައްކާތެރިވާނޭ މަލާއިކަތަކު ނެތިއެއް ނުވެއެވެ.","",""],["","","","فلينظر الإنسان مم خلق","ފަހެ، އިންސާނާ، އޭނާ ހައްދަވާފައިވަނީ ކޮންއެއްޗަކުންކަން ބަލައިފާ ހުށިކަމެވެ!","",""],["","","","خلق من ماء دافق","އޭނާ ހައްދަވާފައިވަނީ، މައިކަށްޓާއި، މޭމަތީގެ ކަށިތަކާ ދެމެދުން ނުކުންނަ، ގަދަޔަށް އޮހޮރިގެންދާ ފެނަކުންނެވެ.","",""],["","","","يخرج من بين الصلب والترائب","އޭނާ ހައްދަވާފައިވަނީ، މައިކަށްޓާއި، މޭމަތީގެ ކަށިތަކާ ދެމެދުން ނުކުންނަ، ގަދަޔަށް އޮހޮރިގެންދާ ފެނަކުންނެވެ.","",""],["","","","إنه على رجعه لقادر","ހަމަކަށަވަރުން، އެކަލާނގެއީ، އެ އިންސާނާ އަލުން ދިރުމަކަށް ފޮނުއްވުމުގެ މައްޗަށް ކުޅަދުންވަންތަ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","يوم تبلى السرائر","ހިތްތަކުގައިވާ ސިއްރުތައް ފާޅުކުރައްވައި، އިމްތިހާނުކުރައްވާ ދުވަހެވެ.","",""],["","","","فما له من قوة ولا ناصر","ފަހެ، އޭނާޔަށް އެއްވެސް ބާރެއް، އަދި ނަސްރު ދޭނޭ މީހަކުވެސް ނުވެއެވެ.","",""],["","","","والسماء ذات الرجع","ވާރޭވެއްސާ އުޑު ގަންދެއްވަމެވެ.","",""],["","","","والأرض ذات الصدع","އަދި ގަސްފަޅާ ބިން ގަންދެއްވަމެވެ.","",""],["","","","إنه لقول فصل","ހަމަކަށަވަރުން، އެ ގުރްއާނަކީ، ހައްގާއި، ބާތިލު ވަކިކުރާ ތެދުބަސްފުޅެއްކަން ކަށަވަރެވެ.","",""],["","","","وما هو بالهزل","އަދި ކުޅޭކުޅޭ އެއްޗެއްކަމުގައި އެ ގުރްއާން ނުވެއެވެ.","",""],["","","","إنهم يكيدون كيدا","ހަމަކަށަވަރުން، އެއުރެން (ކަލޭގެފާނާ ދެކޮޅަށް) މަކަރުވެރި ރޭވުމެއް ރާވަތެވެ.","",""],["","","","وأكيد كيدا","އަދި ތިމަންރަސްކަލާނގެވެސް ރޭއްވެވުމެއް ރާއްވަވަމެވެ.","",""],["","","","فمهل الكافرين أمهلهم رويدا","ފަހެ، ކާފިރުންނަށް ކަލޭގެފާނު މުހުލަތެއް ދެއްވާށެވެ! ކުޑަހިނދުކޮޅަކަށް އެއުރެންނަށް ލަސްކޮށްލައްވާށެވެ!","",""],["","","","بسم الله الرحمن الرحيم سبح اسم ربك الأعلى","ކަލޭގެފާނުގެ ވެރި، އެންމެ މަތިވެރި ރަސްކަލާނގެ އިސްމުފުޅުން ކަލޭގެފާނު ތަސްބީހަ ވިދާޅުވާށެވެ!","",""],["","","","الذي خلق فسوى","އެކަލާނގެއީ (އެންމެހާ ތަކެތި) ހައްދަވައި، ދެން އެ ހެއްދެވުން ފުރިހަމަކުރެއްވި ރަސްކަލާނގެއެވެ.","",""],["","","","والذي قدر فهدى","އަދި އެކަލާނގެއީ (އެންމެހާ ތަކެތި) މިންވަރުކުރައްވައި، ދެން (އެތަކެއްޗަށް) މަގުދެއްކެވި ރަސްކަލާނގެއެވެ.","",""],["","","","والذي أخرج المرعى","އަދި އެކަލާނގެއީ، ފަތްޕިލާވެލި ފެޅުއްވި ރަސްކަލާނގެއެވެ.","",""],["","","","فجعله غثاء أحوى","އަދި އެކަލާނގެ އެތަކެތި، ކަޅުކުލައިގެ ހިކި ކުނޑިތަކެއް ކަމުގައި ލެއްވިއެވެ.","",""],["","","","سنقرئك فلا تنسى","ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނު ކިޔަވައިވިދާޅުވާ ބޭކަލަކު ކަމުގައި ލައްވާހުށީމެވެ. ފަހެ، ކަލޭގެފާނު (އެ ގުރްއާން) ހަނދުމަފުޅެއް ނުނެތޭނެތެވެ.","",""],["","","","إلا ما شاء الله إنه يعلم الجهر وما يخفى","(ހަނދުމަފުޅު ނެތުމަށް) ﷲ އިރާދަކުރެއްވި އެއްޗެއް މެނުވީއެވެ. ހަމަކަށަވަރުން، ފާޅުވެގެންވާ ކަންތަކާއި، ވަންހަނާވެގެންވާ ކަންތައް، އެކަލާނގެ ދެނެވޮޑިގެންވެތެވެ.","",""],["","","","ونيسرك لليسرى","އަދި ފަސޭހަވެގެންވާ މަގަށް، ތިމަންރަސްކަލާނގެ ކަލޭގެފާނަށްޓަކައި މަގު ފަހިކޮށްދެއްވާހުށީމެވެ.","",""],["","","","فذكر إن نفعت الذكرى","ފަހެ، ހަނދުމަކޮށްދިނުން މަންފާކުރާނަމަ، ކަލޭގެފާނު (އެއުރެންނަށް) ހަނދުމަކޮށްދެއްވާށެވެ!","",""],["","","","سيذكر من يخشى","(ﷲއަށް) ބިރުވެތިވާ މީހާ، ހަނދުމަކޮށް އުޅޭނެތެވެ.","",""],["","","","ويتجنبها الأشقى","އަދި އަބާއްޖަވެރިކަން އެންމެ ބޮޑުމީހާ، އެކަމުން ދުރުހެލިވާނެތެވެ.","",""],["","","","الذي يصلى النار الكبرى","އެމީހާއީ، ބޮޑުވެގެންވާ ނަރަކައަށް ވަންނާނޭ މީހެކެވެ.","",""],["","","","ثم لا يموت فيها ولا يحيى","ދެން އެމީހަކު އެތާނގައި މަރެއްވެސް ނުވާނެއެވެ. އަދި (އަރާމުހުރި ދިރުމަކުން) ނުވެސް ދިރޭނޭމެއެވެ.","",""],["","","","قد أفلح من تزكى","(ކާފިރުކަމުން) ތާހިރުވެ، އަދި އެމީހާގެ ވެރިރަސްކަލާނގެ އިސްމުފުޅު ހަނދުމަކޮށް، ނަމާދުކުޅަމީހާ ކާމިޔާބުވެއްޖެކަން ކަށަވަރެވެ.","",""],["","","","وذكر اسم ربه فصلى","(ކާފިރުކަމުން) ތާހިރުވެ، އަދި އެމީހާގެ ވެރިރަސްކަލާނގެ އިސްމުފުޅު ހަނދުމަކޮށް، ނަމާދުކުޅަމީހާ ކާމިޔާބުވެއްޖެކަން ކަށަވަރެވެ.","",""],["","","","بل تؤثرون الحياة الدنيا","އަދި ކިއެއްތަ! އާޚިރަތްގެ ހެޔޮކަން ބޮޑުވެފައި، ދެމިހުރުން ބޮޑުވެގެންވާ ޙާލު ވެސް، ތިޔަބައިމީހުން ދުނިޔޭގެ ދިރިއުޅުން އިސްކުރަމުއެވެ.","",""],["","","","والآخرة خير وأبقى","އަދި ކިއެއްތަ! އާޚިރަތްގެ ހެޔޮކަން ބޮޑުވެފައި، ދެމިހުރުން ބޮޑުވެގެންވާ ޙާލު ވެސް، ތިޔަބައިމީހުން ދުނިޔޭގެ ދިރިއުޅުން އިސްކުރަމުއެވެ.","",""],["","","","إن هذا لفي الصحف الأولى","ހަމަކަށަވަރުން، މިވާހަކަތައް، އިހުގެ ފަތްފުށްތަކުގައިވާކަން ކަށަވަރެވެ.","",""],["","","","صحف إبراهيم وموسى","އިބްރާހީމްގެފާނާއި، މޫސާގެފާނަށް ބާވައިލެއްވި ފަތްފުށްތަކުގައެވެ.","",""],["","","","بسم الله الرحمن الرحيم هل أتاك حديث الغاشية","ބިރުވެރިކަމާއިގެން އެންމެންނަށް ކުރިމަތިވެގެންއަންނާނޭ ކަންތަކުގެ ވާހަކަ(އެބަހީ: ގިޔާމަތްގެ ވާހަކަ) ކަލޭގެފާނާ ހަމަޔަށް އައިސްފައިވޭތޯއެވެ؟","",""],["","","","وجوه يومئذ خاشعة","އެދުވަހުން، ދެރަވެ ނިކަމެތިވެގެންވާ މޫނުތަކެއް ވެއެވެ.","",""],["","","","عاملة ناصبة","މަސައްކަތްތެރި، ވަރުބަލި މޫނުތަކެކެވެ.","",""],["","","","تصلى نارا حامية","ހޫނުކަން ގަދަވެގެންވާ ނަރަކަޔަށް އެއުރެން ވަންނާނެތެވެ.","",""],["","","","تسقى من عين آنية","ހޫނުކަން ނިހާޔަތަށް ގޮސްފައިވާ ފެންއާރަކުން އެއުރެންނަށް ބޯންދެއްވާނެތެވެ.","",""],["","","","ليس لهم طعام إلا من ضريع","ކަށިހުރި، ވިހަ މޭވާޔަކުން މެނުވީ، އެއުރެންނަކަށް ކާނާއެއް ނުވެއެވެ.","",""],["","","","لا يسمن ولا يغني من جوع",") އެ ކެއުމަކުން (ހަށިގަނޑަކަށް ބާރެއް ނުދޭނެތެވެ. އަދި ބަނޑުހައި ހޫނުކަން ފިލުވައެއް ނުމެދޭނޭމެއެވެ.","",""],["","","","وجوه يومئذ ناعمة","އެދުވަހުން ނިއުމަތް ލިބިގެންވާ، އުފާވެރި މޫނުތަކެއް ވެއެވެ.","",""],["","","","لسعيها راضية","ދުނިޔޭގައި އެއުރެންކުޅަ މަސައްކަތަށް ރުހިގެންވެއެވެ.","",""],["","","","في جنة عالية","މަތިވެރިވެގެންވާ ސުވަރުގޭގައެވެ.","",""],["","","","لا تسمع فيها لاغية",") ގެއްލުންދެނިވި (ބޭކާރު ވާހަކައެއް، އެތާނގައި އެއުރެން ނާހާނެތެވެ.","",""],["","","","فيها عين جارية","ހިނގަހިނގާ ހުންނަ ފެންއާރެއް އެތާނގައިވެއެވެ.","",""],["","","","فيها سرر مرفوعة","އުފުލިގެންވާ ދާންތައް އެތާނގައިވެއެވެ.","",""],["","","","وأكواب موضوعة","އަދި ބެހެއްޓިގެންވާ ތަށިތައްވެސްމެއެވެ.","",""],["","","","ونمارق مصفوفة","އަދި އެތުރިގެންވާ ބާލީސްތައްވެސްމެއެވެ.","",""],["","","","وزرابي مبثوثة","އަދި ފެތުރިގެންވާ ދޫލަތައްވެސްމެއެވެ.","",""],["","","","أفلا ينظرون إلى الإبل كيف خلقت","ފަހެ، ޖަމަލު ހައްދަވާފައިވަނީ، ކޮންފަދައަކުން ކަމާމެދު އެއުރެން ޖަމަލަށް ނުބަލަނީހެއްޔެވެ.","",""],["","","","وإلى السماء كيف رفعت","އަދި އުޑު އުފުއްލަވާފައިވަނީ، ކޮންފަދައަކުން ކަމާމެދު އެއުރެން އުޑަށް ނުބަލަނީހެއްޔެވެ؟","",""],["","","","وإلى الجبال كيف نصبت","އަދި ފަރުބަދަތައް ކޮޅަށް ނަންގަވާފައިވަނީ، ކޮންފަދައަކުން ކަމާމެދު އެއުރެން ފަރުބަދަތަކަށް ނުބަލަނީހެއްޔެވެ؟","",""],["","","","وإلى الأرض كيف سطحت","އަދި ބިން ފަތުރުއްވާފައިވަނީ، ކޮންފަދައަކުން ކަމާމެދު އެއުރެން ބިމަށް ނުބަލަނީހެއްޔެވެ؟","",""],["","","","فذكر إنما أنت مذكر","ފަހެ، ކަލޭގެފާނު) އެއުރެންނަށް (ހަނދުމަކޮށް ދެއްވާށެވެ! ކަލޭގެފާނު ވާކަން ކަށަވަރީ، ހަނދުމަކޮށްދެއްވާ ބޭކަލަކު ކަމުގައެވެ.","",""],["","","","لست عليهم بمصيطر","އެއުރެންގެ މައްޗަށް ބާރު ހިންގަވާ ބޭކަލަކު ކަމުގައި ކަލޭގެފާނު ނުވެއެވެ.","",""],["","","","إلا من تولى وكفر","ފުރަގަސްދީ، ކާފިރުވި މީހަކަށް މެނުވީއެވެ.","",""],["","","","فيعذبه الله العذاب الأكبر","ފަހެ، ﷲ، އެމީހަކަށް ބޮޑުވެގެންވާ އަޒާބުން އަޒާބު ދެއްވާނެތެވެ.","",""],["","","","إن إلينا إيابهم","ހަމަކަށަވަރުން، އެއުރެން އެނބުރި އައުންވަނީ، ތިމަންރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","ثم إن علينا حسابهم","ދެން އެއުރެންގެ ހިސާބު ބެއްލެވުން ވަނީވެސް، ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެއަށެވެ.","",""],["","","","بسم الله الرحمن الرحيم والفجر","ފަތިސް ގަންދެއްވަމެވެ.","",""],["","","","وليال عشر","އަދި ދިހަ ރޭ ގަންދެއްވަމެވެ.","",""],["","","","والشفع والوتر","އަދި ހިރިތަކެއްޗާއި، އޮނަހިރި ތަކެތި ގަންދެއްވަމެވެ.","",""],["","","","والليل إذا يسر","އަދި ރޭގަނޑު ވޭތުވެދާހިނދު، ރޭގަނޑު ގަންދެއްވަމެވެ.","",""],["","","","هل في ذلك قسم لذي حجر","ބުއްދީގެ ވެރިޔަކަށް އެކަންކަމުގައި (ފުދޭވަރުގެ) ހުވަޔެއް ވާކަން ކަށަވަރެވެ.","",""],["","","","ألم تر كيف فعل ربك بعاد","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، ޢާދު ބާގައިމީހުންނާމެދު ކަންތައް ކުރެއްވިގޮތް ކަލޭގެފާނަށް އެނގިވަޑައިނުގަންނަވާތޯއެވެ؟","",""],["","","","إرم ذات العماد","އެއީ ތަނބުތަކުގެ ވެރި، އިރަމެވެ ކިއުނު ރަށުގެ އަހުލުވެރިންނެވެ.","",""],["","","","التي لم يخلق مثلها في البلاد","އެ ބިނާތަކަކީ، ރަށްތަކުގައި އެފަދަ ބިނާތަކެއް ހެދިފައި ނުވާފަދަ ބިނާތަކެކެވެ.","",""],["","","","وثمود الذين جابوا الصخر بالواد","އަދި ޘަމޫދު ބާގައިމީހުންނާ މެދުގައިވެސްމެއެވެ. އެއުރެންނީ، ވާދީގައި ހިލަކަނޑައި، ގެދޮރު އަޅައި އުޅުނު މީހުންނެވެ.","",""],["","","","وفرعون ذي الأوتاد","އަދި ލަޝްކަރުތަކުގެ ވެރި ފިރްޢައުނާ މެދުގައިވެސްމެއެވެ.","",""],["","","","الذين طغوا في البلاد","އެއުރެންނީ، ރަށްތަކުގައި އަނިޔާވެރިކަމުގައި ހައްދުފަހަނަޅައިފައިވާ މީހުންނެވެ.","",""],["","","","فأكثروا فيها الفساد","ފަހެ، އެއުރެން އެ ރަށްތަކުގައި ފަސާދަވެރިކަން ގިނަކުޅައޫއެވެ.","",""],["","","","فصب عليهم ربك سوط عذاب","ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް އަޒާބުގެ ބާވަތްތައް އޮއްސެވިއެވެ.","",""],["","","","إن ربك لبالمرصاد","ހަމަކަށަވަރުން، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ (އެއުރެން ކުރާ ކަންތައް) ބެއްލެވުމުގައި ވޮޑިގެންވާކަން ކަށަވަރެވެ.","",""],["","","","فأما الإنسان إذا ما ابتلاه ربه فأكرمه ونعمه فيقول ربي أكرمن","ފަހެ، އިންސާނާ ދަންނާށެވެ! އޭނާގެ ވެރިރަސްކަލާނގެ، އޭނާ އިމްތިހާނުކުރައްވައި، އަދި އޭނާ މާތްކުރައްވައި، އަދި އޭނާޔަށް ނިއުމަތް ދެއްވައިފިހިނދު، ފަހެ، އޭނާ ބުނެތެވެ. ތިމަންގެ ވެރިރަސްކަލާނގެ ތިމަން މާތްކުރައްވައިފިއެވެ.","",""],["","","","وأما إذا ما ابتلاه فقدر عليه رزقه فيقول ربي أهانن","އަދި ދަންނާށެވެ! އެކަލާނގެ، އެ އިންސާނާ އިމްތިހާނުކުރައްވައި، އަދި އޭނާގެ ރިޒްގު ދަތިކުރައްވައިފިހިނދު، ފަހެ، އޭނާ ބުނެތެވެ. ތިމަންގެ ވެރިރަސްކަލާނގެ، ތިމަން ނިކަމެތިކުރައްވައިފިއެވެ.","",""],["","","","كلا بل لا تكرمون اليتيم","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. އަދި ކިއެއްތަ! ތިޔަބައިމީހުން ޔަތީމުންނަށް މާތްކޮށެއް ނުހިތަމުއެވެ.","",""],["","","","ولا تحاضون على طعام المسكين","އަދި ތިޔަބައިމީހުން މިސްކީނުންނަށް ކާންދިނުމުގެ މައްޗަށް އެކަކު އަނެކަކަށް ބާރުއަޅައެއް ނޫޅެމުއެވެ.","",""],["","","","وتأكلون التراث أكلا لما","އަދި (ޙަރާމެއް ހަލާލެއް ނުބަލައި) ތިޔަބައިމީހުން، ވާރުތަ މުދާ ގިނަގިނައިން ކައިއުޅެމުއެވެ.","",""],["","","","وتحبون المال حبا جما","އަދި ތިޔަބައިމީހުން ގަދަވެގެންވާ ލޯތްބަކުން، މުދަލަށް ލޯބިކުރަމުއެވެ.","",""],["","","","كلا إذا دكت الأرض دكا دكا","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ފުނޑުފުނޑުވެ، ބިންގަނޑު ކުނޑިކުނޑިވެގެން ދާހިނދެވެ.","",""],["","","","وجاء ربك والملك صفا صفا","އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ވަޑައިގަންނަވާނެއެވެ. އަދި މަލާއިކަތުން ސަފުސަފަށް ވަޑައިގަންނަވާނެތެވެ.","",""],["","","","وجيء يومئذ بجهنم يومئذ يتذكر الإنسان وأنى له الذكرى","އަދި އެދުވަހުން ނަރަކަ ގެންނަވާނެތެވެ. އެދުވަހުން އިންސާނާ ހަނދުމަކުރާނެތެވެ. އެ ހަނދާންކުރުމުން އޭނާޔަށް ފައިދާއެއްކުރާނީ ކޮންފަދައަކުން ހެއްޔެވެ؟","",""],["","","","يقول يا ليتني قدمت لحياتي","އެދުވަހުން އޭނާ ބުނާނެތެވެ. އޭ ސަހަރޯއެވެ! ތިމަންގެ އާޚިރަތްގެ ހަޔާތަށްޓަކައި (ހެޔޮ) ޢަމަލެއް އިސްކުޅަނަމަ، ކިހާރަނގަޅުވީސް ހެއްޔެވެ؟","",""],["","","","فيومئذ لا يعذب عذابه أحد","ފަހެ، އެދުވަހުން އެކަލާނގެ އޭނާޔަށް ދެއްވާފަދަ އަޒާބެއް އެހެން އެކަކަށްވެސް ނުދެވޭނެތެވެ.","",""],["","","","ولا يوثق وثاقه أحد","އަދި އެކަލާނގެ، އޭނާ ހައްޔަރުކުރައްވާ ފަދައިން، އެހެން އެކަކަށްވެސް ހައްޔަރެއް ނުކުރެވޭނެތެވެ.","",""],["","","","يا أيتها النفس المطمئنة","އޭ ހިތްހަމަޖެހިގެންވާ ފުރާނަޔާއެވެ!","",""],["","","","ارجعي إلى ربك راضية مرضية","ރުހިގެންހުރެ، ރުހުން ލިބިގެންވާ ޙާލު، ތިބާގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް އެނބުރިދާށެވެ!","",""],["","","","فادخلي في عبادي","ފަހެ، ތިމަންރަސްކަލާނގެ އަޅުންގެ ތެރެޔަށް ވަންނާށެވެ!","",""],["","","","وادخلي جنتي","އަދި ތިމަންރަސްކަލާނގެ ސުވަރުގެޔަށް ވަންނާށެވެ!","",""],["","","","بسم الله الرحمن الرحيم لا أقسم بهذا البلد","ކަލޭގެފާނު މިރަށުގައި ހުންނަވާ ޙާލު، މިރަށް) އެބަހީ: މައްކާ (ގަންދެއްވައި ހުވާ ވަހީކުރައްވަމެވެ.","",""],["","","","وأنت حل بهذا البلد","ކަލޭގެފާނު މިރަށުގައި ހުންނަވާ ޙާލު، މިރަށް) އެބަހީ: މައްކާ (ގަންދެއްވައި ހުވާ ވަހީކުރައްވަމެވެ.","",""],["","","","ووالد وما ولد","އަދި އުފަންކުރި މީހާއާއި، އޭނާޔަށް އުފަންވީހާ ބަޔަކު ގަންދެއްވަމެވެ. (އެބަހީ: އާދަމުގެފާނާއި އާދަމުގެ ދަރިންނެވެ.)","",""],["","","","لقد خلقنا الإنسان في كبد","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އިންސާނާ ހައްދަވައި، ވަރުބަލިވުމާއި ގަދަ މަސައްކަތުގެ ތެރެޔަށް ލެއްވީމެވެ.","",""],["","","","أيحسب أن لن يقدر عليه أحد","އެކަކުވެސް އެ އިންސާނާގެ މައްޗަށް ބާރު ހިންގުމަށް ކުޅަދާނަވެގެން ނުވާނޭކަމަށް އޭނާ ހީކުރަނީހެއްޔެވެ؟","",""],["","","","يقول أهلكت مالا لبدا","އޭނާ ބުނެތެވެ. ގިނަވެގެންވާ މުދާ ތިމަން ޚަރަދު ކޮށް ނެތިކޮށްފީމެވެ.","",""],["","","","أيحسب أن لم يره أحد","އެކަކުވެސް އޭނާ ނުދެކޭކަމަށް އޭނާ ހީކުރަނީހެއްޔެވެ؟","",""],["","","","ألم نجعل له عينين","ތިމަންރަސްކަލާނގެ އޭނާޔަށް، ދެލޮލާއި، ދުލަކާއި، ދެތުންފަތް ނުލައްވަން ހެއްޔެވެ؟","",""],["","","","ولسانا وشفتين","ތިމަންރަސްކަލާނގެ އޭނާޔަށް، ދެލޮލާއި، ދުލަކާއި، ދެތުންފަތް ނުލައްވަން ހެއްޔެވެ؟","",""],["","","","وهديناه النجدين","އަދި ދެމަގަށް ތިމަންރަސްކަލާނގެ އޭނާޔަށް މަގުދެއްކެވީމެވެ.","",""],["","","","فلا اقتحم العقبة","ފަހެ، ދަތިކަންހުރިމަގަށް އެ އިންސާނާވަދެ، އެމަގުން ނުހިނގީ ކީއްވެގެންހެއްޔެވެ؟","",""],["","","","وما أدراك ما العقبة","ދަތިކަންހުރި މަގަކީ، ކޮންމަގެއްކަން، ކަލޭގެފާނަށް އަންގައިދިނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","فك رقبة",") އެއީ (އަޅަކު މިނިވަންކުރުމެވެ.","",""],["","","","أو إطعام في يوم ذي مسغبة","ނުވަތަ ބަނޑުހައިހޫނުކަން ފެތުރިފައިވާ ދުވަހެއްގައި ކާންދިނުމެވެ.","",""],["","","","يتيما ذا مقربة","ގާތްތިމާގެ ޔަތީމަކަށެވެ.","",""],["","","","أو مسكينا ذا متربة","ނުވަތަ އަތްމަތި ދަތިވެފައިވާ މިސްކީނަކަށެވެ.","",""],["","","","ثم كان من الذين آمنوا وتواصوا بالصبر وتواصوا بالمرحمة","ދެން އީމާންވެ، އަދި ކެތްތެރިވުމަށް އެކަކު އަނެކަކަށް ވަސިއްޔަތް ކޮށް، އަދި މީސްތަކުންނަށް ރަޙިމު ބެހެއްޓުމަށް އެކަކު އަނެކަކަށް ވަސިއްޔަތް ކޮށް އުޅުނުމީހުންގެ ތެރެއިން އޭނާ ވާނެތެވެ.","",""],["","","","أولئك أصحاب الميمنة","ކަނާތްފަރާތުގެ މީހުންނީ، އެއުރެންނެވެ.","",""],["","","","والذين كفروا بآياتنا هم أصحاب المشأمة","އަދި ތިމަންރަސްކަލާނގެ އާޔަތްތަކަށް ކާފިރުވި މީހުންނީ، އެއީ ވާތްފަރާތުގެ މީހުންނެވެ.","",""],["","","","عليهم نار مؤصدة","އެއުރެންނަށް ހުރީ، ބަންދުކުރައްވާފައިވާ ނަރަކަޔެވެ.","",""],["","","","بسم الله الرحمن الرحيم والشمس وضحاها","އިރާއި، އޭގެ އަލިކަން ގަންދެއްވަމެވެ.","",""],["","","","والقمر إذا تلاها","އަދި ހަނދު އޭގެ ފަހަތުންދާހިނދު ހަނދު، ގަންދެއްވަމެވެ.","",""],["","","","والنهار إذا جلاها","އަދި ދުވާލު، އެ އިރު ފާޅުކޮށްފިހިނދު، އެ ދުވާލު ގަންދެއްވަމެވެ.","",""],["","","","والليل إذا يغشاها","އަދި ރޭގަނޑު، އެ އިރު ނިވާކުރާހިނދު، އެ ރޭގަނޑު ގަންދެއްވަމެވެ.","",""],["","","","والسماء وما بناها","އަދި އުޑާއި، އެ އުޑު ބިނާކުރެއްވި ކަލާނގެ ގަންދެއްވަމެވެ.","",""],["","","","والأرض وما طحاها","އަދި ބިމާއި، އެ ބިން ފެތުރުއްވި ކަލާނގެ ގަންދެއްވަމެވެ.","",""],["","","","ونفس وما سواها","އަދި ނަފްސާއި، އެ ނަފްސު ފުރިހަމަކުރެއްވި ކަލާނގެ ގަންދެއްވަމެވެ.","",""],["","","","فألهمها فجورها وتقواها","ފަހެ، އެކަލާނގެ އެ ނަފްސަށް (ގެއްލުންހުރި) ނުބައިގޮތާއި (ފައިދާހުރި) ހެޔޮގޮތް އެނގުމުގެ ވިސްނުން ދެއްވިއެވެ.","",""],["","","","قد أفلح من زكاها","އެ ތަފްސު ތާހިރު ކޮށްފިމީހާ، ކާމިޔާބުވެއްޖެކަން ކަށަވަރެވެ.","",""],["","","","وقد خاب من دساها","އަދި އެ ނަފްސަށް އުނިކަން ދީފިމީހާ، ނާކާމިޔާބުވެއްޖެކަން ކަށަވަރެވެ.","",""],["","","","كذبت ثمود بطغواها","ޘަމޫދު ބާގައިމީހުން، އެއުރެންގެ އަނިޔާވެރިކަމުން (އެއުރެންގެ ނަބިއްޔާ) ދޮގުކުރޫއެވެ.","",""],["","","","إذ انبعث أشقاها","އެއުރެންކުރެ އެންމެ އަބާއްޖަވެރިމީހާ (ޖަމަލު މެރުމަށް) އަވަސްވެގަތްހިނދެވެ.","",""],["","","","فقال لهم رسول الله ناقة الله وسقياها","ފަހެ، އެއުރެންނަށް ﷲގެ ރަސޫލާ (އެބަހީ: ސާލިހުގެފާނު) ވިދާޅުވިއެވެ. ﷲގެ ޖަމަލަށާއި، އޭގެ ބުއިމަށް ރައްކާތެރިވާށެވެ!","",""],["","","","فكذبوه فعقروها فدمدم عليهم ربهم بذنبهم فسواها","ފަހެ، އެއުރެން އެކަލޭގެފާނުގެ ބަސްފުޅު ދޮގުކުޅައޫއެވެ. ދެން އެއުރެން އެ ޖަމަލު މަރައިލޫއެވެ. ފަހެ، އެއުރެންގެ ފާފައިގެ ސަބަބުން އެއުރެންގެ ވެރިރަސްކަލާނގެ އެއުރެންގެ މައްޗަށް އަޒާބު ފޮނުއްވިއެވެ. އަދި އެއުރެން އެންމެން، އެ އަޒާބުގައި ހަމަހަމަ ކުރެއްވިއެވެ.","",""],["","","","ولا يخاف عقباها","އަދި އެ އަޒާބުގެ ނަތީޖާއާމެދު، އެކަލާނގެ ބިރުވެތިވެވޮޑިގެނެއްނުވެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم والليل إذا يغشى","ރޭގަނޑު އިރު ނިވައިކުރާހިނދު، އެ ރޭގަނޑު ގަންދެއްވަމެވެ.","",""],["","","","والنهار إذا تجلى","ދުވާލު ފާޅުވެ، އަލިވެއްޖެހިނދު، އެ ދުވާލު ގަންދެއްވަމެވެ.","",""],["","","","وما خلق الذكر والأنثى","އަދި ފިރިހެން، އަންހެން، ދެ ޖިންސު ހެއްދެވި ކަލާނގެ ގަންދެއްވަމެވެ.","",""],["","","","إن سعيكم لشتى","ހަމަކަށަވަރުން، އެއުރެންގެ ޢަމަލުތައް ތަފާތުވެގެންވާކަން ކަށަވަރެވެ.","",""],["","","","فأما من أعطى واتقى","ފަހެ) މުދަލުން (ހޭދަކޮށް) ﷲއަށް (ތަގުވާވެރިވެ، އަދި އެންމެ ހެޔޮބަސް ތެދުކުރިމީހާ ދަންނާށެވެ!","",""],["","","","وصدق بالحسنى","ފަހެ) މުދަލުން (ހޭދަކޮށް) ﷲއަށް (ތަގުވާވެރިވެ، އަދި އެންމެ ހެޔޮބަސް ތެދުކުރިމީހާ ދަންނާށެވެ!","",""],["","","","فسنيسره لليسرى","ފަހެ، ތިމަންރަސްކަލާނގެ ފަސޭހަކަން ހުރިމަގަށް އެމީހަކަށް މަގު ފަހިކޮށްދެއްވާ ހުށީމެވެ.","",""],["","","","وأما من بخل واستغنى","ފަހެ، ތިމަންރަސްކަލާނގެ ފަސޭހަކަން ހުރިމަގަށް އެމީހަކަށް މަގު ފަހިކޮށްދެއްވާ ހުށީމެވެ.","",""],["","","","وكذب بالحسنى","އަދި ދަހިވެތިވެ، ﷲ ފިޔަވައި އަމިއްލަޔަށް ފުދިގެންކަމަށްހީކޮށް، އަދި އެންމެ ހެޔޮބަސް ދޮގުކުރިމީހާ ދަންނާށެވެ!","",""],["","","","فسنيسره للعسرى","ފަހެ، ތިމަންރަސްކަލާނގެ ދަތިކަންހުރި މަގަށް އެމީހަކަށް މަގު ފަހިކޮށްދެއްވާ ހުށީމެވެ.","",""],["","","","وما يغني عنه ماله إذا تردى","އަދި އެމީހާ) ނަރަކަޔަށް (ވެއްޓޭހިނދު، އެމީހާގެ މުދާ އެމީހާޔަށް އެއްވެސްކަމެއް ފުއްދައެއް ނުދޭނެތެވެ.","",""],["","","","إن علينا للهدى","ހަމަކަށަވަރުން، ތެދުމަގު ދެއްކެވުންވަނީ، ތިމަންރަސްކަލާނގެއަށްކަން ކަށަވަރެވެ.","",""],["","","","وإن لنا للآخرة والأولى","އަދި ހަމަކަށަވަރުން، އާޚިރަތާއި، ދުނިޔޭގެ ހުރިހާކަމެއް މިލްކުވެގެންވަނީ، ތިމަންރަސްކަލާނގެއަށްކަން ކަށަވަރެވެ.","",""],["","","","فأنذرتكم نارا تلظى","ފަހެ، އަނދައަނދާހުރި ނަރަކައިގެ ވާހަކައިން، ތިމަންރަސްކަލާނގެ ތިޔަބައިމީހުންނަށް އިންޒާރުކުރެއްވީމެވެ.","",""],["","","","لا يصلاها إلا الأشقى","ބޮޑުވެގެންވާ އަބާއްޖަވެރިޔަކު މެނުވީ، އެ ނަރަކަޔަކަށް ނުވަންނާނެތެވެ.","",""],["","","","الذي كذب وتولى","އެމީހަކީ، ދޮގުކޮށް، އަދި އެނބުރި ފުރަގަސްދިން މީހާއެވެ.","",""],["","","","وسيجنبها الأتقى","އަދި ތަގުވާވެރިކަން ބޮޑުމީހާ، އެ ނަރަކަޔާ ދުރުކުރައްވާނެތެވެ.","",""],["","","","الذي يؤتي ماله يتزكى","އެމީހާއީ، އެމީހާ ތާހިރު ވެގަތުމަށްޓަކައި، އޭނާގެ މުދާ ހޭދަކުރާ މީހާއެވެ.","",""],["","","","وما لأحد عنده من نعمة تجزى","އެހެންމީހެއްގެ ފަރާތުން އޭނާޔަށް ލިބޭނެ ހެޔޮކަމެއްގެ ބަދަލުގައެއް ނޫނެވެ.","",""],["","","","إلا ابتغاء وجه ربه الأعلى","އެހެނެއްކަމަކު) އޭނާ ހޭދަކުރަނީ (އޭނާގެ ވެރި، މަތިވެރިވަންތަ ރަސްކަލާނގެ ވަޖުހުފުޅު އަދައިގެންނެވެ.","",""],["","","","ولسوف يرضى","އަދި ނިކަންހުރެ އޭނާ ރުހޭނެކަން ކަށަވަރެވެ.","",""],["","","","بسم الله الرحمن الرحيم والضحى","ދުވާލުގެ ކުރީކޮޅު ގަންދެއްވަމެވެ.","",""],["","","","والليل إذا سجى","އަދި ރޭގަނޑު އަނދިރިކަން ފެތުރި، ހިމޭންވާހިނދު، އެ ރޭގަނޑު ގަންދެއްވަމެވެ.","",""],["","","","ما ودعك ربك وما قلى","ކަލޭގެފާނު ވެރިރަސްކަލާނގެ، ކަލޭގެފާނު ދޫކޮށެއް ނުލައްވަތެވެ. އަދި ނުރުހުންވެވޮޑިއެއް ނުގަންނަވަތެވެ.","",""],["","","","وللآخرة خير لك من الأولى","އަދި ކަލޭގެފާނަށްޓަކައި، ދުނިޔެއަށްވުރެ، އާޚިރަތް ހެޔޮކަން ބޮޑުކަން ކަށަވަރެވެ.","",""],["","","","ولسوف يعطيك ربك فترضى","އަދި ނިކަންހުރެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، ކަލޭގެފާނަށް ދެއްވާނެކަން ކަށަވަރެވެ. ދެން ކަލޭގެފާނު ރުހިވަޑައިގަންނަވާނެތެވެ.","",""],["","","","ألم يجدك يتيما فآوى","ކަލޭގެފާނު ޔަތީމަކު ކަމުގައިވަނިކޮށް އެކަލާނގެ ކަލޭގެފާނު ދެކެވޮޑިގެން ނުވޭހެއްޔެވެ؟ ދެން އެކަލާނގެ، ކަލޭގެފާނަށް ހިޔާވަހިކަން ދެއްވިއެވެ.","",""],["","","","ووجدك ضالا فهدى","އަދި ކަލޭގެފާނު ހައިރާން ވެވަޑައިގެންވަނިކޮށް، އެކަލާނގެ ކަލޭގެފާނު ދެކެވޮޑިގަތެވެ. ދެން އެކަލާނގެ ކަލޭގެފާނަށް މަގުދެއްކެވިއެވެ.","",""],["","","","ووجدك عائلا فأغنى","އަދި ފަގީރަކު ކަމުގައި ކަލޭގެފާނުވާތީ، އެކަލާނގެ ކަލޭގެފާނު ދެކެވޮޑިގަތެވެ. ދެން އެކަލާނގެ ކަލޭގެފާނު މުއްސަނދިކުރެއްވިއެވެ.","",""],["","","","فأما اليتيم فلا تقهر","ދަންނާށެވެ! ފަހެ، ކަލޭގެފާނު، ޔަތީމު ކުއްޖާ ނިކަމެތިކޮށް ނުލައްވާށެވެ!","",""],["","","","وأما السائل فلا تنهر","އަދި ދަންނާށެވެ! ފަހެ، ކަމަކަށްއެދި އަންނަ މީހާޔަށް، ކަލޭގެފާނު އަޑުލައި ނަހައްދަވާށެވެ!","",""],["","","","وأما بنعمة ربك فحدث","އަދި ދަންނާށެވެ! ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ދެއްވި ނިއުމަތްގެ ވާހަކައިން، ފަހެ، ކަލޭގެފާނު ވާހަކަ ދައްކަވައި އުޅުއްވާށެވެ!","",""],["","","","بسم الله الرحمن الرحيم ألم نشرح لك صدرك","ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނުގެ ހިތްޕުޅު ކަލޭގެފާނަށްޓަކައި ތަނަވަސްކޮށް ނުދެއްވަންތޯއެވެ؟","",""],["","","","ووضعنا عنك وزرك","އަދި ކަލޭގެފާނު އުފުއްލަވާ ބުރަ، ކަލޭގެފާނުގެ ކިބައިން ތިމަންރަސްކަލާނގެ ލުއިކުރެއްވީމެވެ.","",""],["","","","الذي أنقض ظهرك","އެއީ ކަލޭގެފާނުގެ ބުރިކަށިފުޅަށް ބުރަކަންދީފައިވާ ކަންތަކެވެ.","",""],["","","","ورفعنا لك ذكرك","އަދި ކަލޭގެފާނަށްޓަކައި ތިމަންރަސްކަލާނގެ، ކަލޭގެފާނުގެ ނަންފުޅު މަތިވެރިކުރެއްވީމެވެ.","",""],["","","","فإن مع العسر يسرا","ފަހެ، ހަމަކަށަވަރުން، އުނދަގޫކަމާއެކު ފަސޭހަކަންވެއެވެ.","",""],["","","","إن مع العسر يسرا","ހަމަކަށަވަރުން، އުނދަގޫކަމާއެކު ފަސޭހަކަންވެއެވެ.","",""],["","","","فإذا فرغت فانصب","ފަހެ، ކަލޭގެފާނު) ދީނަށް ގޮވައިލެއްވުމުގެ މަސައްކަތުން (އަވަދިވެވަޑައިގަންނަވާހިނދު، ފަހެ، ކަލޭގެފާނު) އަޅުކަން ކުރެއްވުމުގައި (ވަރުބަލިވެ ވަޑައިގަންނަވާށެވެ!","",""],["","","","وإلى ربك فارغب","އަދި ހަމައެކަނި، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށް، ފަހެ، ކަލޭގެފާނު އެދިވަޑައިގަންނަވާށެވެ!","",""],["","","","بسم الله الرحمن الرحيم والتين والزيتون","ވައްތީންޏާއި، ޒައިތޫނި ގަންދެއްވަމެވެ.","",""],["","","","وطور سينين","އަދި ޠޫރުސައިނާ ގަންދެއްވަމެވެ.","",""],["","","","وهذا البلد الأمين","އަދި އަމާން ކަން ލިބިގެންވާ މި ރަށް (އެބަހީ: މައްކާ) ގަންދެއްވަމެވެ.","",""],["","","","لقد خلقنا الإنسان في أحسن تقويم","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ، އެންމެ ރިވެތި ޞޫރަގައި އިންސާނާ ހެއްދެވީމެވެ.","",""],["","","","ثم رددناه أسفل سافلين","ދެން ތިމަންރަސްކަލާނގެ، އެ އިންސާނާ (ނަރަކައިގެ) އަޑީގެ އެންމެ އަޑިޔަށް ރައްދުކުރެއްވީމެވެ.","",""],["","","","إلا الذين آمنوا وعملوا الصالحات فلهم أجر غير ممنون","އީމާންވެ ސާލިހު ޢަމަލުތައްކުޅަ މީހުން މެނުވީއެވެ. ފަހެ، އެއުރެންނަށް، ކެނޑިގެން ނުދާނޭ ދަރުމަ ހުއްޓެވެ.","",""],["","","","فما يكذبك بعد بالدين","އެއަށްފަހުވެސް ޖަޒާދެއްވުމުގެ ދުވަހާމެދު އިންކާރުކުރަން، ތިބާޔަށް ޖައްސަނީ ފަހެ، ކޮންކަމެއް ހެއްޔެވެ؟","",""],["","","","أليس الله بأحكم الحاكمين","ހުކުމްކުރައްވާ އެންމެ ޢަދުލުވެރި ރަސްކަލާނގެ ކަމުގައި، ﷲ ވޮޑިގެންނުވޭހެއްޔެވެ؟","",""],["","","","بسم الله الرحمن الرحيم اقرأ باسم ربك الذي خلق","ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ އިސްމުފުޅުން ކަލޭގެފާނު ކިޔަވައި ވިދާޅުވާށެވެ! އެކަލާނގެއީ) ހުރިހާ ތަކެއްޗެއް (ހެއްދެވި ރަސްކަލާނގެއެވެ.","",""],["","","","خلق الإنسان من علق","ގަނޑުލޭކޮޅަކުން އެކަލާނގެ އިންސާނާ ހެއްދެވިއެވެ.","",""],["","","","اقرأ وربك الأكرم","ކަލޭގެފާނު ކިޔަވައި ވިދާޅުވާށެވެ! އަދި ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއީ، އެންމެ ދީލަތިވަންތަ ރަސްކަލާނގެއެވެ.","",""],["","","","الذي علم بالقلم","އެކަލާނގެއީ، ގަލަމުން) ލިޔަން (އުނގަންނައިދެއްވި ރަސްކަލާނގެއެވެ.","",""],["","","","علم الإنسان ما لم يعلم","އިންސާނާއަށް އޭނާ ނުދަންނަ ކަންތައް، އެކަލާނގެ އުނގަންނައިދެއްވިއެވެ.","",""],["","","","كلا إن الإنسان ليطغى","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ހަމަކަށަވަރުން، އިންސާނާ އަނިޔާވެރިކަމުގައި ހައްދުފަހަނަޅައިދާކަން ކަށަވަރެވެ.","",""],["","","","أن رآه استغنى","އޭނާ އަމިއްލަޔަށް ފުދިގެންފިކަމަށް އޭނާޔަށް ފެނުމުންނެވެ.","",""],["","","","إن إلى ربك الرجعى","ހަމަކަށަވަރުން، އެނބުރި ދިޔުންވަނީ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ ހަޒުރަތަށެވެ.","",""],["","","","أرأيت الذي ينهى","އަޅަކު ނަމާދުކޮށްފި ހިނދު، އެކަން ނަހީކޮށް، މަނާކުރާ މީހާ ތިބާ ދުށީމުހެއްޔެވެ؟","",""],["","","","عبدا إذا صلى","އަޅަކު ނަމާދުކޮށްފި ހިނދު، އެކަން ނަހީކޮށް، މަނާކުރާ މީހާ ތިބާ ދުށީމުހެއްޔެވެ؟","",""],["","","","أرأيت إن كان على الهدى","ތިބާ ޚަބަރު ދީބަލާށެވެ! އޭނާ ތެދުމަގުގައި ވީނަމަވެސް، ނުވަތަ ތަގުވާވެރިވުމަށް އަމުރުކުރިނަމަވެސް ހެއްޔެވެ؟","",""],["","","","أو أمر بالتقوى","ތިބާ ޚަބަރު ދީބަލާށެވެ! އޭނާ ތެދުމަގުގައި ވީނަމަވެސް، ނުވަތަ ތަގުވާވެރިވުމަށް އަމުރުކުރިނަމަވެސް ހެއްޔެވެ؟","",""],["","","","أرأيت إن كذب وتولى","ތިބާ ޚަބަރު ދީ ބަލާށެވެ! އޭނާ ދޮގުކޮށް ފުރަގަސްދިންނަމަވެސް ހެއްޔެވެ؟","",""],["","","","ألم يعلم بأن الله يرى","ހަމަކަށަވަރުން، ﷲ ދެކެވޮޑިގެންވާކަން އޭނާ ނުދަންނަނީ ހެއްޔެވެ؟","",""],["","","","كلا لئن لم ينته لنسفعا بالناصية","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ހަމަކަށަވަރުން، އޭނާ އެކަންތައް ހުއްޓައިނުލިނަމަ، ތިމަންރަސްކަލާނގެ އޭނާގެ ނިތްގަނޑުގައި ހިއްޕަވައި ނަރަކަޔަށް ގެންދަވާހުށީމެވެ.","",""],["","","","ناصية كاذبة خاطئة","އެއީ ދޮގުވެރި، ކުށްވެރި ނިތްގަނޑެކެވެ.","",""],["","","","فليدع ناديه","ފަހެ، އޭނާޔާއެކު ޖަލްސާކުރާ އެކުވެރިންނަށް އޭނާ ގޮވައިބަލާށެވެ!","",""],["","","","سندع الزبانية","ނިކަންހުރެ ތިމަންރަސްކަލާނގެ ޒަބާނިއްޔަ މަލާއިކަތުންނަށް ގޮވައިލައްވާހުށީމެވެ.","",""],["","","","كلا لا تطعه واسجد واقترب","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ކަލޭގެފާނު އޭނާޔަށް ކިޔަމަންވެ ވަޑައިނުގަންނަވާށެވެ! އަދި ސަޖިދަކުރައްވައި ނަމާދު ކުރައްވާށެވެ! އަދި) ﷲގެ ހަޒުރަތަށް (ކަލޭގެފާނު ކުއްތަންވެވަޑައިގަންނަވާށެވެ!","",""],["","","","بسم الله الرحمن الرحيم إنا أنزلناه في ليلة القدر","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ އެ ގުރްއާން ބާވައިލެއްވީ ލައިލަތުލް ގަދުރި ވިލޭރޭގައެވެ.","",""],["","","","وما أدراك ما ليلة القدر","އަދި ލައިލަތުލް ގަދުރި ވިލޭރެޔަކީ، ކޮންރެޔެއްކަން ކަލޭގެފާނަށް އަންގައިދިނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","ليلة القدر خير من ألف شهر","ލައިލަތުލް ގަދުރި ވިލޭރޭ، އެއްހާސް މައްސަރަށްވުރެ ހެޔޮކަން ބޮޑެވެ.","",""],["","","","تنزل الملائكة والروح فيها بإذن ربهم من كل أمر","މަލާއިކަތްނާއި، ޖިބްރީލުގެފާނު އެބޭކަލުންގެ ވެރިރަސްކަލާނގެ އިޒުނަ ފުޅާއެކު، ހުރިހާ އަމުރު ފުޅަކާއިގެން އެރޭ ފައިބައިވަޑައިގަންނަވާނެތެވެ.","",""],["","","","سلام هي حتى مطلع الفجر","އެއީ ފަޖުރުގެ އަލިކަން ފާޅުވެއްޖައުމަށްދާނދެން، އަމާންކަމާއި، ސަލާމަތްކަން ލިބިގެންވާ ރެޔެކެވެ.","",""],["","","","بسم الله الرحمن الرحيم لم يكن الذين كفروا من أهل الكتاب والمشركين منفكين حتى تأتيهم البينة","ފޮތުގެ އަހުލުވެރިންނާއި، މުޝްރިކުންގެ ތެރެއިން ކާފިރު ވިމީހުން، ފާޅުވެގެންވާ ދަލީލު އެއުރެންގެ ގާތަށް އަތުވެއްޖައުމަށްދާނދެން އެއުރެން ތިބިގޮތް ދޫކޮށްލާނޭ ބަޔަކުކަމުގައި ނުވެތެވެ.","",""],["","","","رسول من الله يتلو صحفا مطهرة","(އެ ދަލީލަކީ) ﷲގެ ހަޒުރަތުން ފޮނުއްވެވި ރަސޫލެކެވެ. ތާހިރުކުރައްވާފައިވާ ފަތްފުށްތަކެއް އެ ރަސޫލާ ކިޔަވައިދެއްވަތެވެ.","",""],["","","","فيها كتب قيمة","ސީދާވެގެންވާ ހުކުމްތައް، އެ ފަތްފުށްތަކުގައި ވެއެވެ.","",""],["","","","وما تفرق الذين أوتوا الكتاب إلا من بعد ما جاءتهم البينة","އަދި ފާޅުވެގެންވާ ދަލީލު، އެއުރެންގެ ގާތަށް އައުމަށްފަހުގައި މެނުވީ، ފޮތް ލިބުނު މީހުން ބައިބައިވެގެން ނުދެތެވެ.","",""],["","","","وما أمروا إلا ليعبدوا الله مخلصين له الدين حنفاء ويقيموا الصلاة ويؤتوا الزكاة وذلك دين القيمة","ބާތިލު މަގުން އެއްކިބާވެތިބެ، ﷲއަށް އަޅުކަން ޚާލިސްކުރާ ޙާލު، ﷲއަށް އަޅުކަންކުރުމަށާއި، ނަމާދު ގާއިމުކުރުމަށާއި، ޒަކާތްދިނުމަށް މެނުވީ، އެއުރެންނަށް އަމުރުކުރައްވާފައެއް ނުވެތެވެ. އަދި ސީދާވެގެންވާ ދީނަކީ އެއީއެވެ.","",""],["","","","إن الذين كفروا من أهل الكتاب والمشركين في نار جهنم خالدين فيها أولئك هم شر البرية","ހަމަކަށަވަރުން، ފޮތުގެ އަހުލުވެރިންނާއި، މުޝްރިކުންގެ ތެރެއިން ކާފިރު ވިމީހުންވަނީ ނަރަކައިގެ އަލިފާނުގެ ތެރޭގައެވެ. އެތާނގައި އެއުރެން ދެމިތިބެނިވިގޮތުގައެވެ. އެއުރެންނީ، މީސްތަކުންކުރެ ހަމަ އެންމެ ނުބައިމީހުންނެވެ.","",""],["","","","إن الذين آمنوا وعملوا الصالحات أولئك هم خير البرية","ހަމަކަށަވަރުން، އީމާންވެ ސާލިހު ޢަމަލުތައް ކުޅަމީހުން (ދަންނާށެވެ!) އެއުރެންނީ، މީސްތަކުންކުރެ ހަމަ އެންމެ ހެޔޮމީހުންނެވެ.","",""],["","","","جزاؤهم عند ربهم جنات عدن تجري من تحتها الأنهار خالدين فيها أبدا رضي الله عنهم ورضوا عنه ذلك لمن خشي ربه","އެއުރެންގެ ވެރިރަސްކަލާނގެ ހަޒުރަތުގައި، އެއުރެންގެ ޖަޒާއަކީ، އެތާނގެ ދަށުން ކޯރުތައް ހިނގަހިނގާ ހުންނަ ޢަދަނެވެ ކިއުނު ސުވަރުގެތަކެވެ. އެތާނގައި އެއުރެން އަބަދަށް ދެމިތިބެނިވިގޮތުގައެވެ. ﷲއެއުރެންނަށް ރުހިވޮޑިގެންވެތެވެ. އަދި އެއުރެން އެކަލާނގެ (ދެއްވި ނިއުމަތް) އަށް ރުހިގެންވެތެވެ. އެ ނިއުމަތް ލިބޭހުށީ، އެމީހާގެ ވެރިރަސްކަލާނގެއަށް ބިރުވެތިވި މީހަކަށެވެ.","",""],["","","","بسم الله الرحمن الرحيم إذا زلزلت الأرض زلزالها","ބިންގަނޑު އޭގެ (އެންމެފަހުގެ) ހެލިގަތުމުން ހެލިގެންފިހިނދެވެ.","",""],["","","","وأخرجت الأرض أثقالها","އަދި އެ ބިންގަނޑު އޭގެ ބުރަތައް (އެބަހީ: ބިމުގެ އަޑީގައި ވަޅުލެވިފައިވާ ޚަޒާނާ ތަކާއި ކަށްތައް) ނެރެއުކާލައިފިހިނދެވެ.","",""],["","","","وقال الإنسان ما لها","އަދި އެ ބިންގަނޑަށް އެވަނީ ކީއްހެއްޔޭ އިންސާނާ ބުނެފިހިނދެވެ.","",""],["","","","يومئذ تحدث أخبارها","އެދުވަހުން އެ ބިންގަނޑު، އޭގެ ޚަބަރުތަކުގެ ވާހަކަ ދައްކާނެތެވެ.","",""],["","","","بأن ربك أوحى لها","އެއީ ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، އެ ބިމަށް އެކަން އިލްހާމްކުރެއްވީތީއެވެ.","",""],["","","","يومئذ يصدر الناس أشتاتا ليروا أعمالهم","އެދުވަހުން މީސްތަކުން ތަފާތު ބައިބަޔަށް ދާނެތެވެ. (އެއީ) އެއުރެންނަށް، އެއުރެންގެ ޢަމަލުތައް ދެއްކެވުމަށްޓަކައެވެ.","",""],["","","","فمن يعمل مثقال ذرة خيرا يره","ފަހެ، ޒައްރެއްގެ މިންވަރުވިޔަސް، ހެޔޮކަމެއްކޮށްފި މީހާ، އޭނާ އެކަން ދެކޭނެތެވެ.","",""],["","","","ومن يعمل مثقال ذرة شرا يره","އަދި ޒައްރެއްގެ މިންވަރުވިޔަސް، ނުބައިކަމެއްކޮށްފި މީހާ، އޭނާ އެކަން ދެކޭނެތެވެ.","",""],["","","","بسم الله الرحمن الرحيم والعاديات ضبحا","ނޭވާގެ އަޑު އިއްވަމުން، ހަރުކޮށް ދުވާ އަސްތައް ގަންދެއްވަމެވެ.","",""],["","","","فالموريات قدحا","އަދި ފިޔަވަޅުތަކުން އަލިފާން ކަނޑަމުންދުވާ އަސްތައް ގަންދެއްވަމެވެ.","",""],["","","","فالمغيرات صبحا","އަދި ފަތިހުގެ ވަގުތުގައި، ހަމަލާ ދޭ އަސްތައް ގަންދެއްވަމެވެ.","",""],["","","","فأثرن به نقعا","ފަހެ، އެ އަސްތައް، އެ ވަގުތު ހިރަފުސް ބުރުވައިލަތެވެ.","",""],["","","","فوسطن به جمعا","ފަހެ، އެ އަސްތައް އެ ހިރަފުސްތަކުގެ ތެރޭގައި) ދުޝްމަނުންގެ (ބައިގަނޑުގެ މެދަށް ވަދެގަނެތެވެ.","",""],["","","","إن الإنسان لربه لكنود","ހަމަކަށަވަރުން، އިންސާނާއީ، އޭނާގެ ވެރިރަސްކަލާނގެއަށް ހަރާންކޯރުވުން ބޮޑު މީހެކެވެ.","",""],["","","","وإنه على ذلك لشهيد","އަދި ހަމަކަށަވަރުން، އެ އިންސާނާއީ، އެކަމުގެ މައްޗަށް ހެކިވެރިޔަކުކަން ކަށަވަރެވެ.","",""],["","","","وإنه لحب الخير لشديد","އަދި ހަމަކަށަވަރުން، އެ އިންސާނާއީ، މުދަލަށް ލޯބިކުރުންގަދަ މީހެއްކަން ކަށަވަރެވެ.","",""],["","","","أفلا يعلم إذا بعثر ما في القبور","ކަށްވަޅުތަކުގައިވާ ތަކެތި ނެރެ އުކައިލައްވާހިނދު، އަދި ހިތްތަކުގައިވާ ސިއްރުތައް އެއްކޮށް ފާޅުކުރައްވާހިނދު، ފަހެ، އެ އިންސާނާ) އެކަންތައް (ނުދަންނަނީ ހެއްޔެވެ؟","",""],["","","","وحصل ما في الصدور","ކަށްވަޅުތަކުގައިވާ ތަކެތި ނެރެ އުކައިލައްވާހިނދު، އަދި ހިތްތަކުގައިވާ ސިއްރުތައް އެއްކޮށް ފާޅުކުރައްވާހިނދު، ފަހެ، އެ އިންސާނާ) އެކަންތައް (ނުދަންނަނީ ހެއްޔެވެ؟","",""],["","","","إن ربهم بهم يومئذ لخبير","ހަމަކަށަވަރުން، އެއުރެންގެ ވެރިރަސްކަލާނގެއީ، އެދުވަހުން އެއުރެންގެ ކަންތައް މޮޅަށް ދެނެވޮޑިގެންވާ ރަސްކަލާނގެކަން ކަށަވަރެވެ.","",""],["","","","بسم الله الرحمن الرحيم القارعة","ހިތްތަކަށް ބިރުވެރިކަން ގެނެސްދޭ ގިޔާމަތް ދުވަހެވެ.","",""],["","","","ما القارعة","ހިތްތަކަށް ބިރުވެރިކަންގެނެސްދޭ ގިޔާމަތް ދުވަހަކީ، ކޮންދުވަހެއް ހެއްޔެވެ؟","",""],["","","","وما أدراك ما القارعة","އަދި ހިތްތަކަށް ބިރުވެރިކަން ގެނެސްދޭ ގިޔާމަތް ދުވަހަކީ، ކޮންދުވަހެއްކަން ކަލޭގެފާނަށް އަންގައިދިނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","يوم يكون الناس كالفراش المبثوث","ވިއްސިވިހާލިވެގެންދާ ކޮކާތަކެއް ފަދައިން މީސްތަކުންވާނޭ ދުވަހެވެ.","",""],["","","","وتكون الجبال كالعهن المنفوش","އަދި ބުރުވައިލެވޭ ކެހެރިތަކެއް ފަދައިން ފަރުބަދަތައް ވާނޭދުވަހެވެ.","",""],["","","","فأما من ثقلت موازينه","ފަހެ، އެމީހެއްގެ (ހެޔޮކަންތަކުގެ) ތިލަފަތް ބަރުވެއްޖެމީހާ ދަންނާށެވެ!","",""],["","","","فهو في عيشة راضية","ފަހެ، އެމީހާ ވާހުށީ، ރުހިގެންވާ ދިރިއުޅުމެއްގައެވެ. (އެބަހީ: ސުވަރުގޭގައެވެ.)","",""],["","","","وأما من خفت موازينه","އަދި އެމީހެއްގެ ތިލަފަތް ލުއިވެއްޖެމީހާ ދަންނާށެވެ!","",""],["","","","فأمه هاوية","ފަހެ، އޭނާ އުޅޭނެތަނަކީ، ނަރަކައިގެ އަޑިއެވެ.","",""],["","","","وما أدراك ما هيه","އަދި އެއީ ކޮންއެއްޗެއްކަން ކަލޭގެފާނަށް އަންގައިދިނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","نار حامية","އެއީ އަނދައަނދާހުންނަ ނަރަކައިގެ އަލިފާނެވެ.","",""],["","","","بسم الله الرحمن الرحيم ألهاكم التكاثر","(މުދަލާއި ދަރިން (ގިނަކަމަށް އެކަކުއަނެކަކަށް ފަޚުރުވެރިވެ އުޅުން، ތިޔަބައިމީހުން (ﷲގެ މަތިން ހަނދުމަނެއްތައި (މަޝްޣޫލު ކޮށްފިއެވެ.","",""],["","","","حتى زرتم المقابر","ތިޔަބައިމީހުން ކަށްވަޅުތަކަށް ޒިޔާރަތްކޮށްފުމަށް ދާނދެނެވެ. (އެބަހީ: މަރުވެއްޖައުމަށް ދާނދެނެވެ. (","",""],["","","","كلا سوف تعلمون","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ނިކަންހުރެ ތިޔަބައިމީހުންނަށް އެނގޭނެތެވެ.","",""],["","","","ثم كلا سوف تعلمون","ދެންވެސް، ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ނިކަންހުރެ ތިޔަބައިމީހުންނަށް އެނގޭނެތެވެ.","",""],["","","","كلا لو تعلمون علم اليقين","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ޔަގީންކަމުގެ އެނގުމުން ތިޔަބައިމީހުންނަށް އެނގޭނަމައެވެ.","",""],["","","","لترون الجحيم","ހަމަކަށަވަރުން، ތިޔަބައިމީހުން ނަރަކަ ދެކޭނެކަން ކަށަވަރެވެ.","",""],["","","","ثم لترونها عين اليقين","ދެންހަމަ ޔަގީންކަމުގެ ދުށުމުން، ތިޔަބައިމީހުން އެ ނަރަކަ ދެކޭނެކަން ކަށަވަރެވެ.","",""],["","","","ثم لتسألن يومئذ عن النعيم","ދެން އެދުވަހުން ހަމަކަށަވަރުން (ދުނިޔޭގައި ތިޔަބައިމީހުންނަށް ލިބުނު) ނިއުމަތް ތަކާމެދު ތިޔަބައިމީހުންނާ ސުވާލުކުރައްވާނެކަން ކަށަވަރެވެ.","",""],["","","","بسم الله الرحمن الرحيم والعصر","ޒަމާން ގަންދެއްވަމެވެ.","",""],["","","","إن الإنسان لفي خسر","ހަމަކަށަވަރުން، އިންސާނާ ވަނީ، ގެއްލުމެއްގައިކަން ކަށަވަރެވެ.","",""],["","","","إلا الذين آمنوا وعملوا الصالحات وتواصوا بالحق وتواصوا بالصبر","އީމާންވެ ސާލިހު ޢަމަލުތައްކޮށް، އަދި އެކަކު އަނެކަކަށް ހައްގަށް ވަސިއްޔަތް ކޮށް، އަދި އެކަކު އަނެކަކަށް ކެތްތެރިވުމަށް ވަސިއްޔަތް ކޮށްއުޅުނު މީހުން މެނުވީއެވެ.","",""],["","","","بسم الله الرحمن الرحيم ويل لكل همزة لمزة","ޣީބަ ބުނެ، ފުރައްސާރަކޮށް، ވައްތަރުޖައްސާ ކޮންމެ މީހަކަށް، ގެއްލުމާއި ހަލާކުހުށްޓެވެ.","",""],["","","","الذي جمع مالا وعدده","އެމީހާއީ، މުދާ އެއްކޮށް، އެ ގުނައިލަ ގުނައިލައިހުރި މީހާއެވެ.","",""],["","","","يحسب أن ماله أخلده","ހަމަކަށަވަރުން، އޭނާގެ މުދާ އޭނާ ދަމަހައްޓާނެކަމަށް އޭނާ ހީކުރެތެވެ.","",""],["","","","كلا لينبذن في الحطمة","ހަމަހިލާ އެހެންނަކުން ނުވާނެއެވެ. ފުނޑުފުޑުކޮށްލަނިވި ނަރަކަޔަށް އޭނާ އެއްލައިލައްވާނެކަން ކަށަވަރެވެ.","",""],["","","","وما أدراك ما الحطمة","އަދި، ފުނޑުފުނޑުކޮށްލަނިވި ނަރަކަޔަކީ، ކޮންއެއްޗެއްކަން، ކަލޭގެފާނަށް އަންގައިދިނީ ކޮންއެއްޗެއްތޯއެވެ؟","",""],["","","","نار الله الموقدة","(އެއީ) ﷲގެ އަނދައަނދާ ހުންނަ ނަރަކަޔެވެ.","",""],["","","","التي تطلع على الأفئدة","އެއީ ހިތްތަކަށް އޭގެ ހޫނާއި، ވޭން ފޯރުވަނިވި ނަރަކަޔެވެ.","",""],["","","","إنها عليهم مؤصدة","ހަމަކަށަވަރުން، އެ ނަރަކަވާނީ، އެއުރެންނާއެކު، ތަޅުލައްވާފައެވެ.","",""],["","","","في عمد ممددة",") އެއުރެންވާހުށީ) ދިގުވެގެންވާ ތަނބުތަކެއްގައި ބަންނަވާފައެވެ.","",""],["","","","بسم الله الرحمن الرحيم ألم تر كيف فعل ربك بأصحاب الفيل","އެތުގެ އެކުވެރިންނާމެދު (އެބަހީ: ފީލު ބާގައިމީހުންނާމެދު (ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެ، ކަންތައް ކުރެއްވިގޮތް ކަލޭގެފާނަށް އެނގިވަޑައި ނުގަންނަވާތޯއެވެ؟","",""],["","","","ألم يجعل كيدهم في تضليل","އެކަލާނގެ އެއުރެންގެ މަކަރާއި ޙީލަތް، ގެއްލުމެއްގެ ތެރޭގައި ނުލައްވާތޯއެވެ؟","",""],["","","","وأرسل عليهم طيرا أبابيل","އަދި އެކަލާނގެ އެއުރެންގެ މައްޗަށް ބައިބަޔަށް ދޫނިތަކެއް ފޮނުއްވިއެވެ.","",""],["","","","ترميهم بحجارة من سجيل","ގާވެފައިވާ މަށީގެ ހިލަތަކެއް، އެ ދޫނިތައް އެއުރެންނާ ދިމާޔަށް އުކަތެވެ.","",""],["","","","فجعلهم كعصف مأكول","ފަހެ، ޖަނަވާރު ކައިފައިހުރި ހުއިތަކެއް ފަދައިން އެކަލާނގެ އެއުރެން ލެއްވިއެވެ.","",""],["","","","بسم الله الرحمن الرحيم لإيلاف قريش","ގުރައިޝް ވަންހައިގެ މީހުން އެކުވެރިކުރެއްވި ކަމަށްޓަކައެވެ.","",""],["","","","إيلافهم رحلة الشتاء والصيف","ފިނި މޫސުމާއި ހޫނު މޫސުމުގެ ދަތުރުގައި އެއުރެން އެކުވެރިކުރެއްވި ކަމަށްޓަކައެވެ.","",""],["","","","فليعبدوا رب هذا البيت","ފަހެ، މި ގެފުޅުގެ ވެރިރަސްކަލާނގެއަށް އެއުރެން އަޅުކަން ކުރާހުށިކަމެވެ!","",""],["","","","الذي أطعمهم من جوع وآمنهم من خوف","އެކަލާނގެއީ، ބަނޑުހައިހޫނުކަމުގައި ވަނިކޮށް އެއުރެންނަށް ކާންދެއްވައި، އަދި ބިރުވެރިކަމުގައި ވަނިކޮށް އެއުރެންނަށް އަމާންކަންދެއްވި ރަސްކަލާނގެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم أرأيت الذي يكذب بالدين","(ގިޔާމަތް ދުވަހުން) ޖަޒާދެއްވާނޭކަން ދޮގުކުރާމީހާ ކަލޭގެފާނު ދެނެވަޑައިގަންނަވަމުތޯއެވެ؟","",""],["","","","فذلك الذي يدع اليتيم","ފަހެ، އެއީ ޔަތީމު ކުއްޖާ ކޮއްޕައި ދުރަށްލާ މީހާއެވެ.","",""],["","","","ولا يحض على طعام المسكين","އަދި މިސްކީނުންނަށް ކާންދިނުމުގެ މައްޗަށް ބާރުނާޅާ މީހާއެވެ.","",""],["","","","فويل للمصلين","ފަހެ، އެއުރެންގެ ނަމާދާމެދު ޣާފިލުވެ ތިބެ، ނަމާދުކުރާ މީހުންނަށް ގެއްލުމާއި ހަލާކު ހުށްޓެވެ.","",""],["","","","الذين هم عن صلاتهم ساهون","ފަހެ، އެއުރެންގެ ނަމާދާމެދު ޣާފިލުވެ ތިބެ، ނަމާދުކުރާ މީހުންނަށް ގެއްލުމާއި ހަލާކު ހުށްޓެވެ.","",""],["","","","الذين هم يراءون","އެއުރެންނީ، ހަމަ، ކަންދެއްކުމަށް ނަމާދުކުރާ މީހުންނެވެ.","",""],["","","","ويمنعون الماعون","އަދި ހިފައިގެންގުޅޭ ތަކެތި މީހުންނަށްނުދީ، މަނާކުރާ މީހުންނެވެ.","",""],["","","","بسم الله الرحمن الرحيم إنا أعطيناك الكوثر","ހަމަކަށަވަރުން، ތިމަންރަސްކަލާނގެ ގިނަގިނަވެގެންވާ ހެޔޮކަން (އޭގެތެރޭގައި ކައުޘަރު އޭ ކިޔުނު އާރުވެސް) ކަލޭގެފާނަށް ދެއްވީމެވެ.","",""],["","","","فصل لربك وانحر","ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް ކަލޭގެފާނު ނަމާދު ކުރައްވާށެވެ! އަދި ގުރުބާންކުރައްވާށެވެ!","",""],["","","","إن شانئك هو الأبتر","ހަމަކަށަވަރުން، ކަލޭގެފާނު ކޯފާއިސްކުރައްވާ މީހާ އެއީ، ހުރިހާ ހެޔޮކަމަކުން ކެނޑިގެންވާ މީހާއެވެ.","",""],["","","","بسم الله الرحمن الرحيم قل يا أيها الكافرون","ކަލޭގެފާނު ވިދާޅުވާށެވެ! އޭ ކާފިރުންނޭވެ!","",""],["","","","لا أعبد ما تعبدون","ތިޔަބައިމީހުން އަޅުކަންކުރާ ތަކެއްޗަކަށް، ތިމަންކަލޭގެފާނު އަޅުކަމެއް ނުކުރައްވަމެވެ.","",""],["","","","ولا أنتم عابدون ما أعبد","އަދި ތިމަންކަލޭގެފާނު އަޅުކަންކުރައްވާ ހައްގުވަންތަ ﷲއަށް އަޅުކަންކުރާ ބަޔަކު ކަމުގައިވެސް ތިޔަބައިމީހުން ނުވަމުއެވެ.","",""],["","","","ولا أنا عابد ما عبدتم","އަދި ތިޔަބައިމީހުން އަޅުކަންކުޅަ ތަކެއްޗަށް އަޅުކަންކުރާ މީހަކު ކަމުގައި ތިމަންކަލޭގެފާނު ނުވަމެވެ.","",""],["","","","ولا أنتم عابدون ما أعبد","އަދި ތިމަންކަލޭގެފާނު އަޅުކަންކުރައްވާ ހައްގުވަންތަ ﷲއަށް އަޅުކަންކުރާ ބަޔަކު ކަމުގައިވެސް ތިޔަބައިމީހުން ނުވަމުއެވެ.","",""],["","","","لكم دينكم ولي دين","ތިޔަބައިމީހުންނަށް ތިޔަބައިމީހުންގެ ދީނެވެ. އަދި ތިމަންކަލޭގެފާނަށް ތިމަންކަލޭގެފާނުގެ ދީނެވެ.","",""],["","","","بسم الله الرحمن الرحيم إذا جاء نصر الله والفتح","ﷲގެ ނަސްރާއި، ފަތަޙަ އަތުވެއްޖެ ހިނދެވެ.","",""],["","","","ورأيت الناس يدخلون في دين الله أفواجا","އަދި ﷲގެ ދީނަށް މީސްތަކުން ބައިބަޔަށް ވަންނާތީ، ކަލޭގެފާނު ދެކެވަޑައިގެންފި ހިނދެވެ.","",""],["","","","فسبح بحمد ربك واستغفره إنه كان توابا","ފަހެ، ކަލޭގެފާނުގެ ވެރިރަސްކަލާނގެއަށް ހަމްދާއެކު ތަސްބީހަ ވިދާޅުވާށެވެ! އަދި ފާފަފުއްސެވުން އެދިވަޑައިގެން އެކަލާނގެ ހަޒުރަތަށް ދަންނަވާށެވެ! ހަމަކަށަވަރުން، ގިނަގިނައިން ތައުބާ ގަބޫލުކުރައްވާ ކަލަކުކަމުގައި އެކަލާނގެ ވޮޑިގެންވެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم تبت يدا أبي لهب وتب","އަބޫލަހަބުގެ ދެއަތް ގެއްލި ހަލާކުވެދާށިއެވެ! (އެބަހީ: އަބޫލަހަބަށް ހަލާކު ހުށްޓެވެ.) އަދި އޭނާ ގެއްލި ހަލާކުވެއްޖެއެވެ.","",""],["","","","ما أغنى عنه ماله وما كسب","އޭނާގެ މުދަލާއި، އޭނާ ހޯދާފައިވާ ތަކެތި އޭނާޔަކަށް (އެއްވެސް ކަމެއް) ފުއްދައެއް ނުދިނެވެ.","",""],["","","","سيصلى نارا ذات لهب","ހުޅުގަނޑުގެ ވެރި ނަރަކަޔަށް، ނިކަންހުރެ އޭނާ ވަންނާނެތެވެ.","",""],["","","","وامرأته حمالة الحطب","އަދި ދަރު އުފުލަމުން ހިނގާ (އެބަހީ: ދެބައޮޑުވަމުންހިނގާ) އޭނާގެ އަނބިކަނބުލޭގެވެސްމެއެވެ.","",""],["","","","في جيدها حبل من مسد","ކިފުޅިން އަޅާފައިވާ ވަލެއް، އެކަނބުލޭގެ ކަރުގައިވެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم قل هو الله أحد","(އިބަ ނަބިއްޔާ) ވިދާޅުވާށެވެ: އެ އިލާހީ އެއްކައުވަންތަ ﷲ އެވެ.","",""],["","","","الله الصمد","ﷲ އީ (އެންމެހައި ތަކެތި އެ އިލާހަށް ބޭނުން ޖެހިފައިވާ، އަދި އެއްވެސް އެއްޗަކަށް އެ އިލާހު ބޭނުންވެ ވޮޑިގެން ނުވާ) ޞަމަދުވަންތަ އިލާހެވެ.","",""],["","","","لم يلد ولم يولد","އެ އިލާހަށް (އެއްވެސް ދަރިކަލެއް) އުފަންވެފައެއް ނުވެއެވެ. އަދި އެއްވެސް ފަރާތެއްގެ ދަރިކަލެއް ކަމުގައި  އެ އިލާހު އުފަންވެ ވޮޑިގެނެއް ވެސް ނުވެއެވެ.","",""],["","","","ولم يكن له كفوا أحد","އަދި އެ އިލާހާ ކުފޫހަމަވާ (އެއްފަދަ) އެއްވެސް ފަރާތަކު ނުވެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم قل أعوذ برب الفلق","(އިބަ ނަބިއްޔާ) ވިދާޅުވާށެވެ: ފަތިހުގެ ވެރި ރައްބުގެ ހަޒުރަތުން މި އަޅާ ރައްކާތެރިކަމަށް އެދެމެވެ.","",""],["","","","من شر ما خلق","އެ އިލާހު ޚަލްގު ކުރެއްވި (އެންމެހައި) ތަކެތީގެ ނުބައިކަމުން (މި އަޅާ ރައްކާތެރި ކޮށްދެއްވުމަށް އެދެމެވެ.)","",""],["","","","ومن شر غاسق إذا وقب","އަދި ރޭގަނޑު އަނދިރިކަން ވެރިވެގެންނަ ހިނދު، އޭގެ ނުބައިކަމުން ވެސް މެއެވެ.","",""],["","","","ومن شر النفاثات في العقد","އަދި (ސިހުރު ހަދާފައި) ގޮށްގޮށަށް ފުމޭ މީހުންގެ ނުބައިކަމުން ވެސް މެއެވެ.","",""],["","","","ومن شر حاسد إذا حسد","އަދި ހަސަދަވެރިޔާ، ހަސަދަވެރިވާ ހިނދު އޭނާގެ ނުބައިކަމުން ވެސް މެއެވެ.","",""],["","","","بسم الله الرحمن الرحيم قل أعوذ برب الناس","(އިބަ ނަބިއްޔާ) ވިދާޅުވާށެވެ: އިންސާނިއްޔަތުގެ ވެރި ރައްބުގެ ހަޒުރަތުން މި އަޅާ ރައްކާތެރިކަމަށް އެދެމެވެ.","",""],["","","","ملك الناس","(އެ އިލާހީ) އިންސާނިއްޔަތުގެ ރަސްވަންތަ އިލާހެވެ.","",""],["","","","إله الناس","އިންސާނިއްޔަތުގެ (އަޅުކަން ހައްގުވާ) އިލާހެވެ.","",""],["","","","من شر الوسواس الخناس","ފިލާހުރެ ވަސްވާސްދޭ ޝައިތާނާގެ ނުބައިކަމުން (މި އަޅާ ރައްކާތެރި ކޮށްދެއްވުމަށް އެދެމެވެ.)","",""],["","","","الذي يوسوس في صدور الناس","އެއީ އިންސާނުންގެ ހިތްތަކުގައި ވަސްވާސްދޭ ޝައިތާނާއެވެ.","",""],["","","","من الجنة والناس","އެއީ ޖިންނީންނާއި އިންސީންގެ ތެރެއިންވާ (ޝައިތާނުންނެވެ.)","",""]];